window.BOOK={"slug": "isaiah", "name": "Isaiah", "testament": "OT", "orig_label": "Hebrew · WLC", "rtl": true, "translations": [{"id": "kjv", "label": "KJV (1611)"}, {"id": "web", "label": "WEB (modern)"}, {"id": "bsb", "label": "Berean Standard"}, {"id": "asv", "label": "ASV (1901)"}, {"id": "ylt", "label": "Young's Literal"}, {"id": "dra", "label": "Douay-Rheims"}, {"id": "bbe", "label": "Basic English"}, {"id": "geneva", "label": "Geneva (1599)"}, {"id": "wycliffe", "label": "Wycliffe (1382)"}, {"id": "rotherham", "label": "Rotherham Emph."}, {"id": "darby", "label": "Darby"}, {"id": "twenty", "label": "20th Century NT"}, {"id": "jps", "label": "JPS Tanakh (1917)"}, {"id": "acv", "label": "A Conservative Version"}, {"id": "anderson", "label": "Anderson NT (1864)"}, {"id": "haweis", "label": "Haweis NT (1795)"}, {"id": "noyes", "label": "Noyes NT (1869)"}, {"id": "webster", "label": "Webster (1833)"}, {"id": "vulgate", "label": "Vulgate · Latin"}, {"id": "brenton", "label": "LXX · Brenton (Eng)"}], "books": [{"slug": "mark", "name": "Mark", "file": "Mark.html", "testament": "NT"}, {"slug": "matthew", "name": "Matthew", "file": "Matthew.html", "testament": "NT"}, {"slug": "luke", "name": "Luke", "file": "Luke.html", "testament": "NT"}, {"slug": "john", "name": "John", "file": "John.html", "testament": "NT"}, {"slug": "acts", "name": "Acts", "file": "Acts.html", "testament": "NT"}, {"slug": "romans", "name": "Romans", "file": "Romans.html", "testament": "NT"}, {"slug": "1corinthians", "name": "1 Corinthians", "file": "1Corinthians.html", "testament": "NT"}, {"slug": "philippians", "name": "Philippians", "file": "Philippians.html", "testament": "NT"}, {"slug": "colossians", "name": "Colossians", "file": "Colossians.html", "testament": "NT"}, {"slug": "philemon", "name": "Philemon", "file": "Philemon.html", "testament": "NT"}, {"slug": "hebrews", "name": "Hebrews", "file": "Hebrews.html", "testament": "NT"}, {"slug": "genesis", "name": "Genesis", "file": "Genesis.html", "testament": "OT"}, {"slug": "exodus", "name": "Exodus", "file": "Exodus.html", "testament": "OT"}, {"slug": "leviticus", "name": "Leviticus", "file": "Leviticus.html", "testament": "OT"}, {"slug": "numbers", "name": "Numbers", "file": "Numbers.html", "testament": "OT"}, {"slug": "deuteronomy", "name": "Deuteronomy", "file": "Deuteronomy.html", "testament": "OT"}, {"slug": "ruth", "name": "Ruth", "file": "Ruth.html", "testament": "OT"}, {"slug": "job", "name": "Job", "file": "Job.html", "testament": "OT"}, {"slug": "psalms", "name": "Psalms", "file": "Psalms.html", "testament": "OT"}, {"slug": "isaiah", "name": "Isaiah", "file": "Isaiah.html", "testament": "OT"}, {"slug": "ezekiel", "name": "Ezekiel", "file": "Ezekiel.html", "testament": "OT"}, {"slug": "daniel", "name": "Daniel", "file": "Daniel.html", "testament": "OT"}], "chapters": [{"c": 1, "verses": [{"v": 1, "ref": "1:1", "o": "חֲזוֹן֙ יְשַֽׁעְיָ֣הוּ בֶן אָמ֔וֹץ אֲשֶׁ֣ר חָזָ֔ה עַל יְהוּדָ֖ה וִ/ירוּשָׁלִָ֑ם בִּ/ימֵ֨י עֻזִּיָּ֧הוּ יוֹתָ֛ם אָחָ֥ז יְחִזְקִיָּ֖הוּ מַלְכֵ֥י יְהוּדָֽה", "en": {"kjv": "The vision of Isaiah the son of Amoz, which he saw concerning Judah and Jerusalem in the days of Uzziah, Jotham, Ahaz, and Hezekiah, kings of Judah.", "web": "The vision of Isaiah the son of Amoz, which he saw concerning Judah and Jerusalem, in the days of Uzziah, Jotham, Ahaz, and Hezekiah, kings of Judah.", "bsb": "This is the vision concerning Judah and Jerusalem that Isaiah son of Amoz saw during the reigns of Uzziah, Jotham, Ahaz, and Hezekiah, kings of Judah.", "asv": "The vision of Isaiah the son of Amoz, which he saw concerning Judah and Jerusalem, in the days of Uzziah, Jotham, Ahaz, and Hezekiah, kings of Judah.", "ylt": "The Visions of Isaiah son of Amoz, that he hath seen concerning Judah and Jerusalem, in the days of Uzziah, Jotham, Ahaz, Hezekiah, kings of Judah.", "dra": "The vision of Isaiah the Son of Amos, which he saw concerning Juda and Jerusalem in the days of Ozias, Joathan, Achaz, and Ezechias, kings of Juda.", "bbe": "The vision of Isaiah, the son of Amoz, which he saw about Judah and Jerusalem, in the days of Uzziah, Jotham, Ahaz, and Hezekiah, kings of Judah.", "geneva": "A vision of Isaiah, the sonne of Amoz, which he sawe concerning Iudah and Ierusalem: in the dayes of Vzziah, Iotham, Ahaz and Hezekiah Kings of Iudah.", "wycliffe": "The visioun, ether profesie, of Ysaie, the sone of Amos, which he siy on Juda and Jerusalem, in the daies of Osie, of Joathan, of Achas, and of Ezechie, kyngis of Juda.", "rotherham": "The vision of Isaiah son of Amoz, which he saw, concerning Judah and Jerusalem,—in the days of Uzziah Jotham Ahaz Hezekiah—kings of Judah.", "darby": "The vision of Isaiah the son of Amos, which he saw concerning Judah and Jerusalem in the days of Uzziah, Jotham, Ahaz, Hezekiah, kings of Judah.", "twenty": "", "jps": "THE VISION of Isaiah the son of Amoz, which he saw concerning Judah and Jerusalem, in the days of Uzziah, Jotham, Ahaz, and Hezekiah, kings of Judah.", "acv": "The vision of Isaiah the son of Amoz, which he saw concerning Judah and Jerusalem, in the days of Uzziah, Jotham, Ahaz, and Hezekiah, kings of Judah.", "anderson": "", "haweis": "", "noyes": "The visions of Isaiah, the son of Amoz, which he saw concerning Judah and Jerusalem, in the days of Uzziah, Jotham, Ahaz, and Hezekiah, kings of Judah.", "webster": "The vision of Isaiah the son of Amoz, which he saw concerning Judah and Jerusalem in the days of Uzziah, Jotham, Ahaz, [and] Hezekiah, kings of Judah.", "vulgate": "visio Isaiae filii Amos quam vidit super Iudam et Hierusalem in diebus Oziae Ioatham Ahaz Ezechiae regum Iuda;", "brenton": "The vision which Esaias the son of Amos saw, which he saw against Juda, and against Jerusalem, in the reign of Ozias, and Joatham, and Achaz, and Ezekias, who reigned over Judea."}}, {"v": 2, "ref": "1:2", "o": "שִׁמְע֤וּ שָׁמַ֨יִם֙ וְ/הַאֲזִ֣ינִי אֶ֔רֶץ כִּ֥י יְהוָ֖ה דִּבֵּ֑ר בָּנִים֙ גִּדַּ֣לְתִּי וְ/רוֹמַ֔מְתִּי וְ/הֵ֖ם פָּ֥שְׁעוּ בִֽ/י", "en": {"kjv": "Hear, O heavens, and give ear, O earth: for the Lord hath spoken, I have nourished and brought up children, and they have rebelled against me.", "web": "Hear, heavens, and listen, earth; for Yahweh has spoken: “I have nourished and brought up children, and they have rebelled against me.", "bsb": "Listen, O heavens, and give ear, O earth, for the LORD has spoken: “I have raised children and brought them up, but they have rebelled against Me.", "asv": "Hear, O heavens, and give ear, O earth; for Jehovah hath spoken: I have nourished and brought up children, and they have rebelled against me.", "ylt": "Hear, O heavens, and give ear, O earth, For Jehovah hath spoken: Sons I have nourished and brought up, And they--they transgressed against Me.", "dra": "Hear, O ye heavens, and give ear, O earth, for the Lord hath spoken. I have brought up children, and exalted them: but they have despised me.", "bbe": "Give ear, O heavens, and you, O earth, to the word which the Lord has said: I have taken care of my children till they became men, but their hearts have been turned away from me.", "geneva": "Heare, O heauens, and hearken, O earth: for the Lord hath sayde, I haue nourished and brought vp children, but they haue rebelled against me.", "wycliffe": "Ye heuenes, here, and thou erthe, perseyue with eeris, for the Lord spak. Y haue nurschid and Y haue enhaunsid sones; sotheli thei han dispisid me.", "rotherham": "Hear O heavens, And give ear, O earth, for Yahweh, hath spoken:—Sons, have I brought up, and advanced, And, they, have rebelled against me.", "darby": "Hear, [ye] heavens, and give ear, [thou] earth! for Jehovah hath spoken: I have nourished and brought up children; and they have rebelled against me.", "twenty": "", "jps": "Hear, O heavens, and give ear, O earth, for HaShem hath spoken: Children I have reared, and brought up, and they have rebelled against Me.", "acv": "Hear, O heavens, and give ear, O earth, for Jehovah has spoken. I have nourished and brought up sons, and they have rebelled against me.", "anderson": "", "haweis": "", "noyes": "Hear, O heavens, and give ear, O earth! For Jehovah speaketh: \"I have nourished and brought up children, And they have rebelled against me.", "webster": "Hear, O heavens, and give ear, O earth: for the LORD hath spoken, I have nourished and brought up children, and they have rebelled against me.", "vulgate": "audite caeli et auribus percipe terra quoniam Dominus locutus est filios enutrivi et exaltavi ipsi autem spreverunt me;", "brenton": "Hear, O heaven, and hearken, O earth: for the Lord has spoken, saying, I have begotten and reared up children, but they have rebelled against me."}}, {"v": 3, "ref": "1:3", "o": "יָדַ֥ע שׁוֹר֙ קֹנֵ֔/הוּ וַ/חֲמ֖וֹר אֵב֣וּס בְּעָלָ֑י/ו יִשְׂרָאֵל֙ לֹ֣א יָדַ֔ע עַמִּ֖/י לֹ֥א הִתְבּוֹנָֽן", "en": {"kjv": "The ox knoweth his owner, and the ass his master’s crib: but Israel doth not know, my people doth not consider.", "web": "The ox knows his owner, and the donkey his master’s crib; but Israel doesn’t know, my people don’t consider.”", "bsb": "The ox knows its owner, and the donkey its master’s manger, but Israel does not know; My people do not understand.”", "asv": "The ox knoweth his owner, and the ass his master’s crib; but Israel doth not know, my people doth not consider.", "ylt": "An ox hath known its owner, And an ass the crib of its master, Israel hath not known, My people hath not understood.", "dra": "The ox knoweth his owner, and the ass his master's crib: but Israel hath not known me, and my people hath not understood.", "bbe": "Even the ox has knowledge of its owner, and the ass of the place where its master puts its food: but Israel has no knowledge, my people give no thought to me.", "geneva": "The oxe knoweth his owner, and the asse his masters crib: but Israel hath not knowen: my people hath not vnderstand.", "wycliffe": "An oxe knew his lord, and an asse knew the cratche of his lord; but Israel knewe not me, and my puple vndurstood not.", "rotherham": "An ox knoweth, his owner, And an ass his masters crib,—Israel, doth not know, My people doth not consider.", "darby": "The ox knoweth his owner, and the ass his master's crib; Israel doth not know, my people hath no intelligence.", "twenty": "", "jps": "The ox knoweth his owner, and the ass his master's crib; but Israel doth not know, My people doth not consider.", "acv": "The ox knows his owner, and the donkey his master's crib, but Israel does not know; my people does not consider.", "anderson": "", "haweis": "", "noyes": "The ox knoweth his owner, And the ass his master’s crib; But Israel doth not know; My people do not consider.\"", "webster": "The ox knoweth his owner, and the ass his master's crib: [but] Israel doth not know, my people doth not consider.", "vulgate": "cognovit bos possessorem suum et asinus praesepe domini sui Israhel non cognovit populus meus non intellexit;", "brenton": "The ox knows his owner, and the ass his master's crib: but Israel does not know me, and the people has not regarded me."}}, {"v": 4, "ref": "1:4", "o": "ה֣וֹי גּ֣וֹי חֹטֵ֗א עַ֚ם כֶּ֣בֶד עָוֺ֔ן זֶ֣רַע מְרֵעִ֔ים בָּנִ֖ים מַשְׁחִיתִ֑ים עָזְב֣וּ אֶת יְהוָ֗ה נִֽאֲצ֛וּ אֶת קְד֥וֹשׁ יִשְׂרָאֵ֖ל נָזֹ֥רוּ אָחֽוֹר", "en": {"kjv": "Ah sinful nation, a people laden with iniquity, a seed of evildoers, children that are corrupters: they have forsaken the Lord, they have provoked the Holy One of Israel unto anger, they are gone away backward.", "web": "Ah sinful nation, a people loaded with iniquity, a seed of evildoers, children who deal corruptly! They have forsaken Yahweh. They have despised the Holy One of Israel. They are estranged and backward.", "bsb": "Alas, O sinful nation, a people laden with iniquity, a brood of evildoers, children of depravity! They have forsaken the LORD; they have despised the Holy One of Israel and turned their backs on Him.", "asv": "Ah sinful nation, a people laden with iniquity, a seed of evil-doers, children that deal corruptly! they have forsaken Jehovah, they have despised the Holy One of Israel, they are estranged and gone backward.", "ylt": "Ah, sinning nation, a people heavy with iniquity, A seed of evil doers, sons--corrupters! They have forsaken Jehovah, They have despised the Holy One of Israel, They have gone away backward.", "dra": "Woe to the sinful nation, a people laden with iniquity, a wicked seed, ungracious children: they have forsaken the Lord, they have blasphemed the Holy One of Israel, they are gone away backwards.", "bbe": "O nation full of sin, a people weighted down with crime, a generation of evil-doers, false-hearted children: they have gone away from the Lord, they have no respect for the Holy One of Israel, their hearts are turned back from him.", "geneva": "Ah, sinfull nation, a people laden with iniquitie: a seede of the wicked, corrupt children: they haue forsaken the Lord: they haue prouoked the holy one of Israel to anger: they are gone backewarde.", "wycliffe": "Wo to the synful folk, to the puple heuy in wickidnesse, to the weiward seed, to the cursid sones; thei han forsake the Lord, thei han blasfemyd the hooli of Israel, thei ben aliened bacward.", "rotherham": "Alas! a nation—committing sin, a people—burdened with iniquity, a seed—practising wickedness, sons—acting corruptly. They have forsaken Yahweh despised the Holy One of Israel,—Are estranged and gone back.", "darby": "Ah sinful nation, a people laden with iniquity, a seed of evildoers, children that corrupt themselves! They have forsaken Jehovah; they have despised the Holy One of Israel; they are turned away backward.", "twenty": "", "jps": "Ah sinful nation, a people laden with iniquity, a seed of evil-doers, children that deal corruptly; they have forsaken HaShem, they have contemned the Holy One of Israel, they are turned away backward.", "acv": "Ah sinful nation, a people laden with iniquity, a seed of evildoers, sons who deal corruptly! They have forsaken Jehovah. They have despised the Holy One of Israel. They have gone away backward.", "anderson": "", "haweis": "", "noyes": "Ah, sinful nation! a people laden with iniquity! A race of evil-doers! degenerate children! They have forsaken Jehovah; they have despised the Holy One of Israel; They have gone backward.", "webster": "Ah sinful nation, a people laden with iniquity, a seed of evil-doers, children that are corrupters: they have forsaken the LORD, they have provoked the Holy One of Israel to anger, they are gone away backward.", "vulgate": "vae genti peccatrici populo gravi iniquitate semini nequam filiis sceleratis dereliquerunt Dominum blasphemaverunt Sanctum Israhel abalienati sunt retrorsum;", "brenton": "Ah sinful nation, a people full of sins, an evil seed, lawless children: ye have forsaken the Lord, and provoked the Holy One of Israel."}}, {"v": 5, "ref": "1:5", "o": "עַ֣ל מֶ֥ה תֻכּ֛וּ ע֖וֹד תּוֹסִ֣יפוּ סָרָ֑ה כָּל רֹ֣אשׁ לָ/חֳלִ֔י וְ/כָל לֵבָ֖ב דַּוָּֽי", "en": {"kjv": "Why should ye be stricken any more? ye will revolt more and more: the whole head is sick, and the whole heart faint.", "web": "Why should you be beaten more, that you revolt more and more? The whole head is sick, and the whole heart faint.", "bsb": "Why do you want more beatings? Why do you keep rebelling? Your head has a massive wound, and your whole heart is afflicted.", "asv": "Why will ye be still stricken, that ye revolt more and more? the whole head is sick, and the whole heart faint.", "ylt": "Wherefore are ye stricken any more? Ye do add apostasy! Every head is become diseased, and every heart is sick.", "dra": "For what shall I strike you any more, you that increase transgression? the whole head is sick, and the whole heart is sad.", "bbe": "Why will you have more and more punishment? why keep on in your evil ways? Every head is tired and every heart is feeble.", "geneva": "Wherefore shoulde ye be smitten any more? for ye fall away more and more: the whole head is sicke, and the whole heart is heauie.", "wycliffe": "On what thing schal Y smyte you more, that encreessen trespassyng? Ech heed is sijk, and ech herte is morenynge.", "rotherham": "Why should ye be smitten any more? Ye would again turn aside! The whole head is sick, And the whole heart faint:", "darby": "Why should ye be smitten any more? ye will revolt more and more: the whole head is sick, and the whole heart faint.", "twenty": "", "jps": "On what part will ye yet be stricken, seeing ye stray away more and more? The whole head is sick, and the whole heart faint;", "acv": "Why will ye still be stricken, that ye revolt more and more? The whole head is sick, and the whole heart faint.", "anderson": "", "haweis": "", "noyes": "Where can ye be smitten again, Since ye renew your rebellion? The whole head is sick, and the whole heart faint;", "webster": "Why should ye be stricken any more? ye will revolt more and more: the whole head is sick, and the whole heart faint.", "vulgate": "super quo percutiam vos ultra addentes praevaricationem omne caput languidum et omne cor maerens;", "brenton": "Why should ye be smitten any more, transgressing more and more? the whole head is pained, and the whole heart sad."}}, {"v": 6, "ref": "1:6", "o": "מִ/כַּף רֶ֤גֶל וְ/עַד רֹאשׁ֙ אֵֽין בּ֣/וֹ מְתֹ֔ם פֶּ֥צַע וְ/חַבּוּרָ֖ה וּ/מַכָּ֣ה טְרִיָּ֑ה לֹא זֹ֨רוּ֙ וְ/לֹ֣א חֻבָּ֔שׁוּ וְ/לֹ֥א רֻכְּכָ֖ה בַּ/שָּֽׁמֶן", "en": {"kjv": "From the sole of the foot even unto the head there is no soundness in it; but wounds, and bruises, and putrifying sores: they have not been closed, neither bound up, neither mollified with ointment.", "web": "From the sole of the foot even to the head there is no soundness in it: wounds, welts, and open sores. They haven’t been closed, neither bandaged, neither soothed with oil.", "bsb": "From the sole of your foot to the top of your head, there is no soundness— only wounds and welts and festering sores neither cleansed nor bandaged nor soothed with oil.", "asv": "From the sole of the foot even unto the head there is no soundness in it; but wounds, and bruises, and fresh stripes: they have not been closed, neither bound up, neither mollified with oil.", "ylt": "From the sole of the foot--unto the head, There is no soundness in it, Wound, and bruise, and fresh smiting! They have not been closed nor bound, Nor have they softened with ointment.", "dra": "From the sole of the foot unto the top of the head, there is no soundness therein: wounds and bruises and swelling sores: they are not bound up, nor dressed, nor fomented with oil.", "bbe": "The body, from head to foot, is all diseased; it is a mass of open wounds, marks of blows, and broken flesh: the flow of blood has not been stopped, and no oil has been put on the wounds.", "geneva": "From the sole of the foote vnto the head, there is nothing whole therein, but wounds, and swelling, and sores full of corruption: they haue not bene wrapped, nor bound vp, nor mollified with oyle.", "wycliffe": "Fro the sole of the foot til to the nol, helthe is not ther ynne; wounde, and wannesse, and betyng bolnynge is not boundun aboute, nether curid bi medicyn, nether nurschid with oile.", "rotherham": "From the sole of the foot even unto the head, there is in it no soundness, Bruise and stripe and newly-made wound,—They have not been pressed out, nor bound up, nor soothed with oil.", "darby": "From the sole of the foot even unto the head there is no soundness in him; wounds, and weals, and open sores: they have not been dressed, nor bound up, nor mollified with oil.", "twenty": "", "jps": "From the sole of the foot even unto the head there is no soundness in it; but wounds, and bruises, and festering sores: they have not been pressed, neither bound up, neither mollified with oil.", "acv": "From the sole of the foot even to the head there is no soundness in it, but wounds, and bruises, and fresh stripes. They have not been closed nor bound up nor soothed with oil.", "anderson": "", "haweis": "", "noyes": "From the sole of the foot even to the head, there is no soundness in it; It is all bruises, and stripes, and flesh wounds, Neither pressed, nor bound up, nor softened with ointment.", "webster": "From the sole of the foot even to the head [there is] no soundness in [it]; [but] wounds, and bruises, and putrifying sores: they have not been closed, neither bound up, neither mollified with ointment.", "vulgate": "a planta pedis usque ad verticem non est in eo sanitas vulnus et livor et plaga tumens non est circumligata nec curata medicamine neque fota oleo;", "brenton": "From the feet to the head, there is no soundness in them; neither wound, nor bruise, nor festering ulcer are healed: it is not possible to apply a plaister, nor oil, nor bandages."}}, {"v": 7, "ref": "1:7", "o": "אַרְצְ/כֶ֣ם שְׁמָמָ֔ה עָרֵי/כֶ֖ם שְׂרֻפ֣וֹת אֵ֑שׁ אַדְמַתְ/כֶ֗ם לְ/נֶגְדְּ/כֶם֙ זָרִים֙ אֹכְלִ֣ים אֹתָ֔/הּ וּ/שְׁמָמָ֖ה כְּ/מַהְפֵּכַ֥ת זָרִֽים", "en": {"kjv": "Your country is desolate, your cities are burned with fire: your land, strangers devour it in your presence, and it is desolate, as overthrown by strangers.", "web": "Your country is desolate. Your cities are burned with fire. Strangers devour your land in your presence, and it is desolate, as overthrown by strangers.", "bsb": "Your land is desolate; your cities are burned with fire. Foreigners devour your fields before you— a desolation demolished by strangers.", "asv": "Your country is desolate; your cities are burned with fire; your land, strangers devour it in your presence, and it is desolate, as overthrown by strangers.", "ylt": "Your land is a desolation, your cities burnt with fire, Your ground, before you strangers are consuming it, And a desolation as overthrown by strangers!", "dra": "Your land is desolate, your cities are burnt with fire: your country strangers devour before your face, and it shall be desolate as when wasted by enemies.", "bbe": "Your country has become waste; your towns are burned with fire; as for your land, it is overturned before your eyes, made waste and overcome by men from strange lands.", "geneva": "Your land is waste: your cities are burnt with fire: strangers deuoure your lande in your presence, and it is desolate like the ouerthrowe of strangers.", "wycliffe": "Youre lond is forsakun, youre citees ben brent bi fier; aliens deuouren youre cuntrei bifore you, and it schal be disolat as in the distriyng of enemyes.", "rotherham": "Your country—is a desolation, Your cities—are consumed with fire,—Your soil—right before your eyes, foreigners are devouring it, And it is a desolation a very overthrow by foreigners;", "darby": "Your country is desolate; your cities are burned with fire; your land, strangers eat it up in your presence, and it is desolate, as overthrown by strangers.", "twenty": "", "jps": "Your country is desolate; your cities are burned with fire; your land, strangers devour it in your presence, and it is desolate, as overthrown by floods.", "acv": "Your country is desolate. Your cities are burned with fire. Your land-strangers devour it in your presence, and it is desolate, as overthrown by strangers.", "anderson": "", "haweis": "", "noyes": "Your country is desolate; Your cities are burnt with fire; Your ground, strangers devour it before your eyes; It is become desolate, destroyed by an enemy.", "webster": "Your country [is] desolate, your cities [are] burned with fire: your land, strangers devour it in your presence, and [it is] desolate, as overthrown by strangers.", "vulgate": "terra vestra deserta civitates vestrae succensae igni regionem vestram coram vobis alieni devorant et desolabitur sicut in vastitate hostili;", "brenton": "Your land is desolate, your cities burned with fire: your land, strangers devour it in your presence, and it is made desolate, overthrown by strange nations."}}, {"v": 8, "ref": "1:8", "o": "וְ/נוֹתְרָ֥ה בַת צִיּ֖וֹן כְּ/סֻכָּ֣ה בְ/כָ֑רֶם כִּ/מְלוּנָ֥ה בְ/מִקְשָׁ֖ה כְּ/עִ֥יר נְצוּרָֽה", "en": {"kjv": "And the daughter of Zion is left as a cottage in a vineyard, as a lodge in a garden of cucumbers, as a besieged city.", "web": "The daughter of Zion is left like a shelter in a vineyard, like a hut in a field of melons, like a besieged city.", "bsb": "And the Daughter of Zion is abandoned like a shelter in a vineyard, like a shack in a cucumber field, like a city besieged.", "asv": "And the daughter of Zion is left as a booth in a vineyard, as a lodge in a garden of cucumbers, as a besieged city.", "ylt": "And left hath been the daughter of Zion, As a booth in a vineyard, As a lodge in a place of cucumbers--as a city besieged.", "dra": "And the daughter of Sion shall be left as a covert in a vineyard, and as a lodge in a garden of cucumbers, and as a city that is laid waste.", "bbe": "And the daughter of Zion has become like a tent in a vine-garden, like a watchman's house in a field of fruit, like a town shut in by armies.", "geneva": "And the daughter of Zion shall remaine like a cotage in a vineyarde, like a lodge in a garden of cucumbers, and like a besieged citie.", "wycliffe": "And the douytir of Sion, `that is, Jerusalem, schal be forsakun as a schadewynge place in a vyner, and as an hulke in a place where gourdis wexen, and as a citee which is wastid.", "rotherham": "And left is the Daughter of Zion, Like a hut in a vineyard,—Like a lodge in a gourd-plot Like a city besieged.", "darby": "And the daughter of Zion is left, as a booth in a vineyard, as a night-lodge in a cucumber-garden, as a besieged city.", "twenty": "", "jps": "And the daughter of Zion is left as a booth in a vineyard, as a lodge in a garden of cucumbers, as a besieged city.", "acv": "And the daughter of Zion is left as a booth in a vineyard, as a shed in a garden of cucumbers, as a besieged city.", "anderson": "", "haweis": "", "noyes": "And the daughter of Zion is left as a shed in a vineyard, As a hut in a garden of cucumbers, As a besieged city.", "webster": "And the daughter of Zion is left as a cottage in a vineyard, as a lodge in a garden of cucumbers, as a besieged city.", "vulgate": "et derelinquetur filia Sion ut umbraculum in vinea et sicut tugurium in cucumerario sicut civitas quae vastatur;", "brenton": "The daughter of Sion shall be deserted as a tent in a vineyard, and as a storehouse of fruits in a garden of cucumbers, as a besieged city."}}, {"v": 9, "ref": "1:9", "o": "לוּלֵי֙ יְהוָ֣ה צְבָא֔וֹת הוֹתִ֥יר לָ֛/נוּ שָׂרִ֖יד כִּ/מְעָ֑ט כִּ/סְדֹ֣ם הָיִ֔ינוּ לַ/עֲמֹרָ֖ה דָּמִֽינוּ", "en": {"kjv": "Except the Lord of hosts had left unto us a very small remnant, we should have been as Sodom, and we should have been like unto Gomorrah.", "web": "Unless Yahweh of Armies had left to us a very small remnant, we would have been as Sodom; we would have been like Gomorrah.", "bsb": "Unless the LORD of Hosts had left us a few survivors, we would have become like Sodom, we would have resembled Gomorrah.", "asv": "Except Jehovah of hosts had left unto us a very small remnant, we should have been as Sodom, we should have been like unto Gomorrah.", "ylt": "Unless Jehovah of Hosts had left to us a remnant, Shortly--as Sodom we had been, To Gomorrah we had been like!", "dra": "Except the Lord of hosts had left us seed, we had been as Sodom, and we should have been like to Gomorrha.", "bbe": "If the Lord of armies had not kept some at least of us safe, we would have been like Sodom, and the fate of Gomorrah would have been ours.", "geneva": "Except the Lord of hostes had reserued vnto vs, euen a small remnant: we should haue bene as Sodom, and should haue bene like vnto Gomorah.", "wycliffe": "If the Lord of oostis hadde not left seed to vs, we hadden be as Sodom, and we hadden be lijk as Gomorre.", "rotherham": "If, Yahweh of hosts, had not left us a very small remnant, Like Sodom, had we become, Gomorrah, had we resembled.", "darby": "Unless Jehovah of hosts had left us a very small residue, we should have been as Sodom, we should have been like unto Gomorrah.", "twenty": "", "jps": "Except HaShem of hosts had left unto us a very small remnant, we should have been as Sodom, we should have been like unto Gomorrah.", "acv": "Unless Jehovah of hosts had left to us a seed, we should have been as Sodom, we should have been like Gomorrah.", "anderson": "", "haweis": "", "noyes": "Had not Jehovah of hosts left us a small remnant, We had soon become as Sodom; We had been like to Gomorrah.", "webster": "Except the LORD of hosts had left to us a very small remnant, we should have been as Sodom; we should have been like Gomorrah.", "vulgate": "nisi Dominus exercituum reliquisset nobis semen quasi Sodoma fuissemus et quasi Gomorra similes essemus;", "brenton": "And if the Lord of Sabaoth had not left us a seed, we should have been as Sodom, and we should have been made like Gomorrha."}}, {"v": 10, "ref": "1:10", "o": "שִׁמְע֥וּ דְבַר יְהוָ֖ה קְצִינֵ֣י סְדֹ֑ם הַאֲזִ֛ינוּ תּוֹרַ֥ת אֱלֹהֵ֖י/נוּ עַ֥ם עֲמֹרָֽה", "en": {"kjv": "Hear the word of the Lord, ye rulers of Sodom; give ear unto the law of our God, ye people of Gomorrah.", "web": "Hear Yahweh’s word, you rulers of Sodom! Listen to the law of our God, you people of Gomorrah!", "bsb": "Hear the word of the LORD, you rulers of Sodom; listen to the instruction of our God, you people of Gomorrah!", "asv": "Hear the word of Jehovah, ye rulers of Sodom; give ear unto the law of our God, ye people of Gomorrah.", "ylt": "Hear the word of Jehovah, ye rulers of Sodom, Give ear to the law of our God, ye people of Gomorrah,", "dra": "Hear the word of the Lord, ye rulers of Sodom, give ear to the law of our God, ye people of Gomorrha.", "bbe": "Give ear to the word of the Lord, you rulers of Sodom; let your hearts be turned to the law of our God, you people of Gomorrah.", "geneva": "Heare the worde of the Lord, O princes of Sodom: hearken vnto the Law of our God, O people of Gomorah.", "wycliffe": "Ye princes of men of Sodom, here the word of the Lord; and ye puple of Gommorre, perseyue with eeris the lawe of youre God.", "rotherham": "Hear the word of Yahweh, ye rulers of Sodom,—Give ear to the instruction of our God, ye people of Gomorrah:—", "darby": "Hear the word of Jehovah, rulers of Sodom; give ear unto the law of ourGod, people of Gomorrah!", "twenty": "", "jps": "Hear the word of HaShem, ye rulers of Sodom; give ear unto the law of our G-d, ye people of Gomorrah.", "acv": "Hear the word of Jehovah, ye rulers of Sodom, give ear to the law of our God, ye people of Gomorrah.", "anderson": "", "haweis": "", "noyes": "Hear ye the word of Jehovah, ye princes of Sodom! Give ear to the instruction of our God, ye people of Gomorrah!", "webster": "Hear the word of the LORD, ye rulers of Sodom; give ear to the law of our God, ye people of Gomorrah.", "vulgate": "audite verbum Domini principes Sodomorum percipite auribus legem Dei nostri populus Gomorrae;", "brenton": "Hear the word of the Lord, ye rulers of Sodoma; attend to the law of God, thou people of Gomorrha."}}, {"v": 11, "ref": "1:11", "o": "לָ/מָּה לִּ֤/י רֹב זִבְחֵי/כֶם֙ יֹאמַ֣ר יְהוָ֔ה שָׂבַ֛עְתִּי עֹל֥וֹת אֵילִ֖ים וְ/חֵ֣לֶב מְרִיאִ֑ים וְ/דַ֨ם פָּרִ֧ים וּ/כְבָשִׂ֛ים וְ/עַתּוּדִ֖ים לֹ֥א חָפָֽצְתִּי", "en": {"kjv": "To what purpose is the multitude of your sacrifices unto me? saith the Lord: I am full of the burnt offerings of rams, and the fat of fed beasts; and I delight not in the blood of bullocks, or of lambs, or of he goats.", "web": "“What are the multitude of your sacrifices to me?”, says Yahweh. “I have had enough of the burnt offerings of rams, and the fat of fed animals. I don’t delight in the blood of bulls, or of lambs, or of male goats.", "bsb": "“What good to Me is your multitude of sacrifices?” says the LORD. “I am full from the burnt offerings of rams and the fat of well-fed cattle; I take no delight in the blood of bulls and lambs and goats.", "asv": "What unto me is the multitude of your sacrifices? saith Jehovah: I have had enough of the burnt-offerings of rams, and the fat of fed beasts; and I delight not in the blood of bullocks, or of lambs, or of he-goats.", "ylt": "`Why to Me the abundance of your sacrifices? saith Jehovah, I have been satiated with burnt-offerings of rams, And fat of fatlings; And blood of bullocks, and lambs, And he-goats I have not desired.", "dra": "To what purpose do you offer me the multitude of your victims, saith the Lord? I am full, I desire not holocausts of rams, and fat of fatlings, and blood of calves, and lambs, and buck goats.", "bbe": "What use to me is the number of the offerings which you give me? says the Lord; your burned offerings of sheep, and the best parts of fat cattle, are a weariness to me; I take no pleasure in the blood of oxen, or of lambs, or of he-goats.", "geneva": "What haue I to doe with the multitude of your sacrifices, sayth the Lord? I am full of the burnt offerings of rams, and of the fat of fed beasts: and I desire not the blood of bullocks, nor of lambs, nor of goates.", "wycliffe": "Wherto offren ye to me the multitude of youre sacrifices? seith the Lord. Y am ful; Y wolde not the brent sacrifices of wetheris, and the ynnere fatnesse of fatte beestis, and the blood of calues, and of lambren, and of buckis of geet.", "rotherham": "Of what use to me, is your multitude of sacrifices: Saith Yahweh: I am sated with ascending-offerings of rams and the fat of fed beasts,—In the blood of bulls and young rams and he-goats, have I no pleasure.", "darby": "To what purpose is the multitude of your sacrifices unto me? saith Jehovah. I am sated with burnt-offerings of rams, and the fat of fed beasts; and in the blood of bullocks, and of lambs, and of he-goats I take no pleasure.", "twenty": "", "jps": "To what purpose is the multitude of your sacrifices unto Me? saith HaShem; I am full of the burnt-offerings of rams, and the fat of fed beasts; and I delight not in the blood of bullocks, or of lambs, or of he-goats.", "acv": "What to me is the multitude of your sacrifices? says Jehovah. I have had enough of the burnt offerings of rams, and the fat of fed beasts. And I do not delight in the blood of bullocks or of lambs or of he-goats.", "anderson": "", "haweis": "", "noyes": "What to me is the multitude of your sacrifices? saith Jehovah; I am satiated with burnt-offerings of rams, and the fat of fed beasts; In the blood of bullocks and of lambs and of goats I have no delight.", "webster": "To what purpose [is] the multitude of your sacrifices to me? saith the LORD: I am full of the burnt-offerings of rams, and the fat of fed beasts; and I delight not in the blood of bullocks, or of lambs, or of he-goats.", "vulgate": "quo mihi multitudinem victimarum vestrarum dicit Dominus plenus sum holocausta arietum et adipem pinguium et sanguinem vitulorum et agnorum et hircorum nolui;", "brenton": "Of what value to me is the abundance of your sacrifices? saith the Lord: I am full of whole-burnt-offerings of rams; and I delight not in the fat of lambs, and the blood of bulls and goats:"}}, {"v": 12, "ref": "1:12", "o": "כִּ֣י תָבֹ֔אוּ לֵ/רָא֖וֹת פָּנָ֑/י מִי בִקֵּ֥שׁ זֹ֛את מִ/יֶּדְ/כֶ֖ם רְמֹ֥ס חֲצֵרָֽ/י", "en": {"kjv": "When ye come to appear before me, who hath required this at your hand, to tread my courts?", "web": "When you come to appear before me, who has required this at your hand, to trample my courts?", "bsb": "When you come to appear before Me, who has required this of you— this trampling of My courts?", "asv": "When ye come to appear before me, who hath required this at your hand, to trample my courts?", "ylt": "When ye come in to appear before Me, Who hath required this of your hand, To trample My courts?", "dra": "When you came to appear before me, who required these things at your hands, that you should walk in my courts?", "bbe": "At whose request do you come before me, making my house unclean with your feet?", "geneva": "When ye come to appeare before me, who required this of your hands to tread in my courts?", "wycliffe": "Whanne ye camen bifore my siyt, who axide of youre hondis these thingis, that ye schulden go in myn hallys?", "rotherham": "When ye enter to see my face, Who hath required this at your hand trampling my courts?", "darby": "When ye come to appear before me, who hath required this from your hand — to tread my courts?", "twenty": "", "jps": "When ye come to appear before Me, who hath required this at your hand, to trample My courts?", "acv": "When ye come to appear before me, who has required this at your hand-to trample my courts?", "anderson": "", "haweis": "", "noyes": "When ye come to appear before me, Who hath required this of you, to tread my courts?", "webster": "When ye come to appear before me, who hath required this at your hand, to tread my courts?", "vulgate": "cum veneritis ante conspectum meum quis quaesivit haec de manibus vestris ut ambularetis in atriis meis;", "brenton": "neither shall ye come with these to appear before me; for who has required these things at your hands? Ye shall no more tread my court."}}, {"v": 13, "ref": "1:13", "o": "לֹ֣א תוֹסִ֗יפוּ הָבִיא֙ מִנְחַת שָׁ֔וְא קְטֹ֧רֶת תּוֹעֵבָ֛ה הִ֖יא לִ֑/י חֹ֤דֶשׁ וְ/שַׁבָּת֙ קְרֹ֣א מִקְרָ֔א לֹא אוּכַ֥ל אָ֖וֶן וַ/עֲצָרָֽה", "en": {"kjv": "Bring no more vain oblations; incense is an abomination unto me; the new moons and sabbaths, the calling of assemblies, I cannot away with; it is iniquity, even the solemn meeting.", "web": "Bring no more vain offerings. Incense is an abomination to me; new moons, Sabbaths, and convocations: I can’t bear with evil assemblies.", "bsb": "Bring your worthless offerings no more; your incense is detestable to Me— your New Moons, Sabbaths, and convocations. I cannot endure iniquity in a solemn assembly.", "asv": "Bring no more vain oblations; incense is an abomination unto me; new moon and sabbath, the calling of assemblies,—I cannot away with iniquity and the solemn meeting.", "ylt": "Add not to bring in a vain present, Incense--an abomination it is to Me, New moon, and sabbath, calling of convocation! Rendure not iniquity--and a restraint!", "dra": "Offer sacrifice no more in vain: incense is an abomination to me. The new moons, and the sabbaths and other festivals I will not abide, your assemblies are wicked.", "bbe": "Give me no more false offerings; the smoke of burning flesh is disgusting to me, so are your new moons and Sabbaths and your holy meetings.", "geneva": "Bring no more oblations, in vaine: incense is an abomination vnto me: I can not suffer your newe moones, nor Sabbaths, nor solemne dayes (it is iniquitie) nor solemne assemblies.", "wycliffe": "Offre ye no more sacrifice in veyn; encense is abhomynacioun to me; Y schal not suffre neomenye, and sabat, and othere feestis.", "rotherham": "Ye shall not again bring in an empty, present, Incense, an abomination, is that unto me! New moon, and sabbath calling an assembly—I cannot endure, iniquity and sacred festival!", "darby": "Bring no more vain oblations! Incense is an abomination unto me, — new moon and sabbath, the calling of convocations — wickedness and the solemn meeting I cannot bear.", "twenty": "", "jps": "Bring no more vain oblations; it is an offering of abomination unto Me; new moon and sabbath, the holding of convocations-- I cannot endure iniquity along with the solemn assembly.", "acv": "Bring no more vain oblations. Incense is an abomination to me. New moon and sabbath, the calling of assemblies-I cannot bear iniquity and the solemn meeting.", "anderson": "", "haweis": "", "noyes": "Bring no more false oblations! Incense is an abomination to me, The new moon also, and the sabbath, and the calling of the assembly; Iniquity and festivals I cannot endure.", "webster": "Bring no more vain oblations; incense is an abomination to me; the new moons and sabbaths, the calling of assemblies, I cannot endure; [it is] iniquity, even the solemn meeting.", "vulgate": "ne adferatis ultra sacrificium frustra incensum abominatio est mihi neomeniam et sabbatum et festivitates alias non feram iniqui sunt coetus vestri;", "brenton": "Though ye bring fine flour, it is vain; incense is an abomination to me; I cannot bear your new moons, and your sabbaths, and the great day;"}}, {"v": 14, "ref": "1:14", "o": "חָדְשֵׁי/כֶ֤ם וּ/מוֹעֲדֵי/כֶם֙ שָׂנְאָ֣ה נַפְשִׁ֔/י הָי֥וּ עָלַ֖/י לָ/טֹ֑רַח נִלְאֵ֖יתִי נְשֹֽׂא", "en": {"kjv": "Your new moons and your appointed feasts my soul hateth: they are a trouble unto me; I am weary to bear them.", "web": "My soul hates your New Moons and your appointed feasts. They are a burden to me. I am weary of bearing them.", "bsb": "I hate your New Moons and your appointed feasts. They have become a burden to Me; I am weary of bearing them.", "asv": "Your new moons and your appointed feasts my soul hateth; they are a trouble unto me; I am weary of bearing them.", "ylt": "Your new moons and your set seasons hath My soul hated, They have been upon me for a burden, I have been weary of bearing.", "dra": "My soul hateth your new moons, and your solemnities: they are become troublesome to me, I am weary of bearing them.", "bbe": "Your new moons and your regular feasts are a grief to my soul: they are a weight in my spirit; I am crushed under them.", "geneva": "My soule hateth your newe moones and your appointed feastes: they are a burden vnto me: I am weary to beare them.", "wycliffe": "Youre cumpenyes ben wickid; my soule hatith youre calendis and youre solempnytees; tho ben maad diseseful to me, Y trauelide suffrynge.", "rotherham": "Your new moons and your appointed feasts, my soul, hateth,—They have become unto me a burden I am too weary to bear:", "darby": "Your new moons and your set feasts my soul hateth: they are a burden to me; I am wearied of bearing [them].", "twenty": "", "jps": "Your new moons and your appointed seasons My soul hateth; they are a burden unto Me; I am weary to bear them.", "acv": "Your new moons and your appointed feasts my soul hates. They are a trouble to me. I am weary of bearing them.", "anderson": "", "haweis": "", "noyes": "Your new moons and your feasts my soul hateth; They are a burden to me; I am weary of bearing them.", "webster": "Your new moons and your appointed feasts my soul hateth: they are a trouble to me; I am weary to bear [them].", "vulgate": "kalendas vestras et sollemnitates vestras odivit anima mea facta sunt mihi molesta laboravi sustinens;", "brenton": "your fasting, and rest from work, your new moons also, and your feasts my soul hates: ye have become loathsome to me; I will no more pardon your sins."}}, {"v": 15, "ref": "1:15", "o": "וּ/בְ/פָרִשְׂ/כֶ֣ם כַּפֵּי/כֶ֗ם אַעְלִ֤ים עֵינַ/י֙ מִ/כֶּ֔ם גַּ֛ם כִּֽי תַרְבּ֥וּ תְפִלָּ֖ה אֵינֶ֣/נִּי שֹׁמֵ֑עַ יְדֵי/כֶ֖ם דָּמִ֥ים מָלֵֽאוּ", "en": {"kjv": "And when ye spread forth your hands, I will hide mine eyes from you: yea, when ye make many prayers, I will not hear: your hands are full of blood.", "web": "When you spread out your hands, I will hide my eyes from you. Yes, when you make many prayers, I will not hear. Your hands are full of blood.", "bsb": "When you spread out your hands in prayer, I will hide My eyes from you; even though you multiply your prayers, I will not listen. Your hands are covered with blood.", "asv": "And when ye spread forth your hands, I will hide mine eyes from you; yea, when ye make many prayers, I will not hear: your hands are full of blood.", "ylt": "And in your spreading forth your hands, I hide mine eyes from you, Also when ye increase prayer, I do not hear, Your hands of blood have been full.", "dra": "And when you stretch forth your hands, I will turn away my eyes from you: and when you multiply prayer, I will not hear: for your hands are full of blood.", "bbe": "And when your hands are stretched out to me, my eyes will be turned away from you: even though you go on making prayers, I will not give ear: your hands are full of blood.", "geneva": "And when you shall stretch out your hands, I wil hide mine eyes from you: and though ye make many prayers, I wil not heare: for your hands are full of blood.", "wycliffe": "And whanne ye stretchen forth youre hondis, Y schal turne awei myn iyen fro you; and whanne ye multiplien preyer, Y schal not here; for whi youre hondis ben ful of blood.", "rotherham": "Even when ye spread forth your open palms, I hide mine eyes from you; Yea, though ye multiply prayers, I am not hearkening,—Your hands, with deeds of blood, are filled.", "darby": "And when ye spread forth your hands, I will hide mine eyes from you; yea, when ye make many prayers, I will not hear: your hands are full of blood.", "twenty": "", "jps": "And when ye spread forth your hands, I will hide Mine eyes from you; yea, when ye make many prayers, I will not hear; your hands are full of blood.", "acv": "And when ye spread forth your hands, I will hide my eyes from you. Yea, when ye make many prayers, I will not hear; your hands are full of blood.", "anderson": "", "haweis": "", "noyes": "When ye spread forth your hands, I will hide mine eyes from you; Yea, when ye multiply prayers, I will not hear: Your hands are full of blood!", "webster": "And when ye spread forth your hands, I will hide my eyes from you: yes, when ye make many prayers, I will not hear: your hands are full of blood.", "vulgate": "et cum extenderitis manus vestras avertam oculos meos a vobis et cum multiplicaveritis orationem non audiam manus vestrae sanguine plenae sunt;", "brenton": "When ye stretch forth your hands, I will turn away mine eyes from you: and though ye make many supplications, I will not hearken to you; for your hands are full of blood."}}, {"v": 16, "ref": "1:16", "o": "רַחֲצוּ֙ הִזַּכּ֔וּ הָסִ֛ירוּ רֹ֥עַ מַעַלְלֵי/כֶ֖ם מִ/נֶּ֣גֶד עֵינָ֑/י חִדְל֖וּ הָרֵֽעַ", "en": {"kjv": "Wash you, make you clean; put away the evil of your doings from before mine eyes; cease to do evil;", "web": "Wash yourselves, make yourself clean. Put away the evil of your doings from before my eyes. Cease to do evil.", "bsb": "Wash and cleanse yourselves. Remove your evil deeds from My sight. Stop doing evil!", "asv": "Wash you, make you clean; put away the evil of your doings from before mine eyes; cease to do evil;", "ylt": "Wash ye, make ye pure, Turn aside the evil of your doings, from before Mine eyes, Cease to do evil, learn to do good.", "dra": "Wash yourselves, be clean, take away the evil of your devices from my eyes, cease to do perversely,", "bbe": "Be washed, make yourselves clean; put away the evil of your doings from before my eyes; let there be an end of sinning;", "geneva": "Wash you, make you cleane: take away the euill of your workes from before mine eyes: cease to doe euill.", "wycliffe": "Be ye waischun, be ye clene; do ye awei the yuel of youre thouytis fro myn iyen; ceesse ye to do weiwardli, lerne ye to do wel.", "rotherham": "Wash you make you clean, Put away the wickedness of your doings from before mine eyes,—Cease to do evil.", "darby": "Wash you, make you clean; put away the evil of your doings from before mine eyes; — cease to do evil,", "twenty": "", "jps": "Wash you, make you clean, put away the evil of your doings from before Mine eyes, cease to do evil;", "acv": "Wash you, make you clean, put away the evil of your doings from before my eyes. Cease to do evil.", "anderson": "", "haweis": "", "noyes": "Wash you; make you clean; Put away your evil doings from before mine eyes;", "webster": "Wash ye, make yourselves clean; put away the evil of your doings from before my eyes; cease to do evil;", "vulgate": "lavamini mundi estote auferte malum cogitationum vestrarum ab oculis meis quiescite agere perverse;", "brenton": "Wash you, be clean; remove your iniquities from your souls before mine eyes; cease from your iniquities;"}}, {"v": 17, "ref": "1:17", "o": "לִמְד֥וּ הֵיטֵ֛ב דִּרְשׁ֥וּ מִשְׁפָּ֖ט אַשְּׁר֣וּ חָמ֑וֹץ שִׁפְט֣וּ יָת֔וֹם רִ֖יבוּ אַלְמָנָֽה", "en": {"kjv": "Learn to do well; seek judgment, relieve the oppressed, judge the fatherless, plead for the widow.", "web": "Learn to do well. Seek justice. Relieve the oppressed. Judge the fatherless. Plead for the widow.”", "bsb": "Learn to do right; seek justice and correct the oppressor. Defend the fatherless and plead the case of the widow.”", "asv": "learn to do well; seek justice, relieve the oppressed, judge the fatherless, plead for the widow.", "ylt": "Seek judgment, make happy the oppressed, Judge the fatherless, strive for the widow.", "dra": "Learn to do well: seek judgment, relieve the oppressed, judge for the fatherless, defend the widow.", "bbe": "Take pleasure in well-doing; let your ways be upright, keep down the cruel, give a right decision for the child who has no father, see to the cause of the widow.", "geneva": "Learne to doe well: seeke iudgement, relieue the oppressed: iudge the fatherlesse and defend the widowe.", "wycliffe": "Seke ye doom, helpe ye hym that is oppressid, deme ye to the fadirles and modirles child, defende ye a widewe.", "rotherham": "Learn to do well—Seek justice, Correct the oppressor,—Vindicate the fatherless, Plead the cause of the widow,", "darby": "learn to do well: seek judgment, gladden the oppressed, do justice to the fatherless, plead for the widow.", "twenty": "", "jps": "Learn to do well; seek justice, relieve the oppressed, judge the fatherless, plead for the widow.", "acv": "Learn to do good. Seek justice, relieve the oppressed, judge the fatherless, plead for the widow.", "anderson": "", "haweis": "", "noyes": "Cease to do evil; Learn to do well; Seek justice; relieve the oppressed; Defend the fatherless; plead for the widow!", "webster": "Learn to do well; seek judgment, relieve the oppressed, judge the fatherless, plead for the widow.", "vulgate": "discite benefacere quaerite iudicium subvenite oppresso iudicate pupillo defendite viduam;", "brenton": "learn to do well; diligently seek judgment, deliver him that is suffering wrong, plead for the orphan, and obtain justice for the widow."}}, {"v": 18, "ref": "1:18", "o": "לְכוּ נָ֛א וְ/נִוָּֽכְחָ֖ה יֹאמַ֣ר יְהוָ֑ה אִם יִֽהְי֨וּ חֲטָאֵי/כֶ֤ם כַּ/שָּׁנִים֙ כַּ/שֶּׁ֣לֶג יַלְבִּ֔ינוּ אִם יַאְדִּ֥ימוּ כַ/תּוֹלָ֖ע כַּ/צֶּ֥מֶר יִהְיֽוּ", "en": {"kjv": "Come now, and let us reason together, saith the Lord: though your sins be as scarlet, they shall be as white as snow; though they be red like crimson, they shall be as wool.", "web": "“Come now, and let us reason together,” says Yahweh: “Though your sins be as scarlet, they shall be as white as snow. Though they be red like crimson, they shall be as wool.", "bsb": "“Come now, let us reason together,” says the LORD. “Though your sins are like scarlet, they will be as white as snow; though they are as red as crimson, they will become like wool.", "asv": "Come now, and let us reason together, saith Jehovah: though your sins be as scarlet, they shall be as white as snow; though they be red like crimson, they shall be as wool.", "ylt": "Come, I pray you, and we reason, saith Jehovah, If your sins are as scarlet, as snow they shall be white, If they are red as crimson, as wool they shall be!", "dra": "And then come, and accuse me, saith the Lord: if your sins be as scarlet, they shall be made as white as snow: and if they be red as crimson, they shall be white as wool.", "bbe": "Come now, and let us have an argument together, says the Lord: how may your sins which are red like blood be white as snow? how may their dark purple seem like wool?", "geneva": "Come nowe, and let vs reason together, sayth the Lord: though your sinnes were as crimsin, they shalbe made white as snowe: though they were red like skarlet, they shalbe as wooll.", "wycliffe": "And come ye, and repreue ye me, seith the Lord. Thouy youre synnes ben as blood reed, tho schulen be maad whijt as snow; and thouy tho ben reed as vermylioun, tho schulen be whijt as wolle.", "rotherham": "Come, I pray you, and let us settle the dispute Saith Yahweh,—Though your sins be found like scarlet, As snow, shall they be made white, Though they appear red like crimson, As wool, shall they become.", "darby": "Come now, let us reason together, saith Jehovah: though your sins be as scarlet, they shall be as white as snow; though they be red like crimson, they shall be as wool.", "twenty": "", "jps": "Come now, and let us reason together, saith HaShem; though your sins be as scarlet, they shall be as white as snow; though they be red like crimson, they shall be as wool.", "acv": "Come now, and let us reason together, says Jehovah, though your sins be as scarlet, they shall be as white as snow. Though they be red like crimson, they shall be as wool.", "anderson": "", "haweis": "", "noyes": "Come, now, and let us argue together, saith Jehovah. Though your sins be as scarlet, they shall be as white as snow; Though they be red as crimson, they shall be like wool.", "webster": "Come now, and let us reason together, saith the LORD: though your sins are as scarlet, they shall be white as snow, though they are red like crimson, they shall be as wool.", "vulgate": "et venite et arguite me dicit Dominus si fuerint peccata vestra ut coccinum quasi nix dealbabuntur et si fuerint rubra quasi vermiculus velut lana erunt;", "brenton": "And come, let us reason together, saith the Lord: and though your sins be as purple, I will make them white as snow; and though they be as scarlet, I will make them white as wool."}}, {"v": 19, "ref": "1:19", "o": "אִם תֹּאב֖וּ וּ/שְׁמַעְתֶּ֑ם ט֥וּב הָ/אָ֖רֶץ תֹּאכֵֽלוּ", "en": {"kjv": "If ye be willing and obedient, ye shall eat the good of the land:", "web": "If you are willing and obedient, you shall eat the good of the land;", "bsb": "If you are willing and obedient, you will eat the best of the land.", "asv": "If ye be willing and obedient, ye shall eat the good of the land:", "ylt": "If ye are willing, and have hearkened, The good of the land ye consume,", "dra": "If you be willing, and will hearken to me, you shall eat the good things of the land.", "bbe": "If you will give ear to my word and do it, the good things of the land will be yours;", "geneva": "If ye consent and obey, ye shall eate the good things of the land.", "wycliffe": "If ye wolen, and heren me, ye schulen ete the goodis of erthe.", "rotherham": "If ye be willing—and hearken Of the good of the land, shall ye eat;", "darby": "If ye be willing and hearken, ye shall eat the good of the land;", "twenty": "", "jps": "If ye be willing and obedient, ye shall eat the good of the land;", "acv": "If ye are willing and obedient, ye shall eat the good of the land.", "anderson": "", "haweis": "", "noyes": "If ye be willing and obedient, Ye shall consume the good of the land.", "webster": "If ye are willing and obedient, ye shall eat the good of the land:", "vulgate": "si volueritis et audieritis bona terrae comedetis;", "brenton": "And if ye be willing, and hearken to me, ye shall eat the good of the land:"}}, {"v": 20, "ref": "1:20", "o": "וְ/אִם תְּמָאֲנ֖וּ וּ/מְרִיתֶ֑ם חֶ֣רֶב תְּאֻכְּל֔וּ כִּ֛י פִּ֥י יְהוָ֖ה דִּבֵּֽר", "en": {"kjv": "But if ye refuse and rebel, ye shall be devoured with the sword: for the mouth of the Lord hath spoken it.", "web": "but if you refuse and rebel, you shall be devoured with the sword; for the mouth of Yahweh has spoken it.”", "bsb": "But if you resist and rebel, you will be devoured by the sword.” For the mouth of the LORD has spoken.", "asv": "but if ye refuse and rebel, ye shall be devoured with the sword; for the mouth of Jehovah hath spoken it.", "ylt": "And if ye refuse, and have rebelled, By the sword ye are consumed, For the mouth of Jehovah hath spoken.", "dra": "But if you will not, and will provoke me to wrath: the sword shall devour you because the mouth of the Lord hath spoken it.", "bbe": "But if your hearts are turned against me, I will send destruction on you by the sword; so the Lord has said.", "geneva": "But if ye refuse and be rebellious, ye shalbe deuoured with the sword: for the mouth of the Lord hath spoken it.", "wycliffe": "That if ye nylen, and ye terren me to wrathfulnesse, swerd schal deuoure you; for whi the mouth of the Lord spak.", "rotherham": "But, if ye refuse and rebel, With the sword, shall ye be devoured, For, the mouth of Yahweh, hath spoken it.", "darby": "but if ye refuse and rebel, ye shall be devoured with the sword: for the mouth of Jehovah hath spoken.", "twenty": "", "jps": "But if ye refuse and rebel, ye shall be devoured with the sword; for the mouth of HaShem hath spoken.", "acv": "But if ye refuse and rebel, ye shall be devoured with the sword, for the mouth of Jehovah has spoken it.", "anderson": "", "haweis": "", "noyes": "But if ye refuse, and be rebellious, The sword shall consume you; For the mouth of Jehovah hath said it.", "webster": "But if ye refuse and rebel, ye shall be devoured with the sword: for the mouth of the LORD hath spoken [it].", "vulgate": "quod si nolueritis et me provocaveritis ad iracundiam gladius devorabit vos quia os Domini locutum est;", "brenton": "but if ye be not willing, nor hearken to me, a sword shall devour you: for the mouth of the Lord has spoken this."}}, {"v": 21, "ref": "1:21", "o": "אֵיכָה֙ הָיְתָ֣ה לְ/זוֹנָ֔ה קִרְיָ֖ה נֶאֱמָנָ֑ה מְלֵאֲתִ֣י מִשְׁפָּ֗ט צֶ֛דֶק יָלִ֥ין בָּ֖/הּ וְ/עַתָּ֥ה מְרַצְּחִֽים", "en": {"kjv": "How is the faithful city become an harlot! it was full of judgment; righteousness lodged in it; but now murderers.", "web": "How the faithful city has become a prostitute! She was full of justice; righteousness lodged in her, but now murderers.", "bsb": "See how the faithful city has become a harlot! She once was full of justice; righteousness resided within her, but now only murderers!", "asv": "How is the faithful city become a harlot! she that was full of justice! righteousness lodged in her, but now murderers.", "ylt": "How hath a faithful city become a harlot? I have filled it with judgment, Righteousness lodgeth in it--now murderers.", "dra": "How is the faithful city, that was full of judgment, become a harlot? justice dwelt in it, but now murderers.", "bbe": "The upright town has become untrue; there was a time when her judges gave right decisions, when righteousness had a resting-place in her, but now she is full of those who take men's lives.", "geneva": "Howe is the faithfull citie become an harlot? it was full of iudgement, and iustice lodged therein, but now they are murtherers.", "wycliffe": "Hou is the feithful citee ful of dom maad an hoore? riytfulnesse dwellide ther ynne; but now menquelleris dwellen ther ynne.", "rotherham": "How hath she become unchaste!—The city that was Faithful,—Full of justice, Righteousness lodged in her, But, now, murderers!", "darby": "How is the faithful city become a harlot! It was full of judgment; righteousness used to lodge in it, but now murderers.", "twenty": "", "jps": "How is the faithful city become a harlot! She that was full of justice, righteousness lodged in her, but now murderers.", "acv": "How the faithful city has become a harlot! She who was full of justice! Righteousness lodged in her, but now murderers.", "anderson": "", "haweis": "", "noyes": "How is the faithful city become a harlot, She that was full of equity! Once justice dwelt in her, but now murderers!", "webster": "How is the faithful city become a harlot! it was full of judgment; righteousness lodged in it; but now murderers.", "vulgate": "quomodo facta est meretrix civitas fidelis plena iudicii iustitia habitavit in ea nunc autem homicidae;", "brenton": "How has the faithful city Sion, once full of judgment, become a harlot! wherein righteousness lodged, but now murderers."}}, {"v": 22, "ref": "1:22", "o": "כַּסְפֵּ֖/ךְ הָיָ֣ה לְ/סִיגִ֑ים סָבְאֵ֖/ךְ מָה֥וּל בַּ/מָּֽיִם", "en": {"kjv": "Thy silver is become dross, thy wine mixed with water:", "web": "Your silver has become dross, your wine mixed with water.", "bsb": "Your silver has become dross; your fine wine is diluted with water.", "asv": "Thy silver is become dross, thy wine mixed with water.", "ylt": "Thy silver hath become dross, Thy drink polluted with water.", "dra": "Thy silver is turned into dross: thy wine is mingled with water.", "bbe": "Your silver is no longer true metal, your wine is mixed with water.", "geneva": "Thy siluer is become drosse: thy wine is mixt with water.", "wycliffe": "Thi siluer is turned in to dros, ether filthe; thi wyn is medlid with watir.", "rotherham": "Thy silver, hath become dross,—Thy wine, weakened with water;", "darby": "Thy silver is become dross, thy wine is mixed with water:", "twenty": "", "jps": "Thy silver is become dross, thy wine mixed with water.", "acv": "Thy silver has become dross, thy wine mixed with water.", "anderson": "", "haweis": "", "noyes": "Thy silver is become dross; Thy wine is adulterated with water.", "webster": "Thy silver is become dross, thy wine mixed with water:", "vulgate": "argentum tuum versum est in scoriam vinum tuum mixtum est aqua;", "brenton": "Your silver is worthless, thy wine merchants mix the wine with water."}}, {"v": 23, "ref": "1:23", "o": "שָׂרַ֣יִ/ךְ סוֹרְרִ֗ים וְ/חַבְרֵי֙ גַּנָּבִ֔ים כֻּלּ/וֹ֙ אֹהֵ֣ב שֹׁ֔חַד וְ/רֹדֵ֖ף שַׁלְמֹנִ֑ים יָתוֹם֙ לֹ֣א יִשְׁפֹּ֔טוּ וְ/רִ֥יב אַלְמָנָ֖ה לֹֽא יָב֥וֹא אֲלֵי/הֶֽם", "en": {"kjv": "Thy princes are rebellious, and companions of thieves: every one loveth gifts, and followeth after rewards: they judge not the fatherless, neither doth the cause of the widow come unto them.", "web": "Your princes are rebellious, and companions of thieves. Everyone loves bribes, and follows after rewards. They don’t judge the fatherless, neither does the cause of the widow come to them.", "bsb": "Your rulers are rebels, friends of thieves. They all love bribes and chasing after rewards. They do not defend the fatherless, and the plea of the widow never comes before them.", "asv": "Thy princes are rebellious, and companions of thieves; every one loveth bribes, and followeth after rewards: they judge not the fatherless, neither doth the cause of the widow come unto them.", "ylt": "Thy princes are apostates, and companions of thieves, Every one loving a bribe, and pursuing rewards, The fatherless they judge not, And the plea of the widow cometh not to them.", "dra": "Thy princes are faithless, companions of thieves: they all love bribes, they run after rewards. They judge not for the fatherless: and the widow's cause cometh not in to them.", "bbe": "Your chiefs have gone against the Lord, they have become friends of thieves; every one of them is looking for profit and going after rewards; they do not give right decisions for the child who has no father, and they do not let the cause of the widow come before them.", "geneva": "Thy Princes are rebellious and companions of theeues: euery one loueth giftes, and followeth after rewards: they iudge not the fatherlesse, neither doeth the widowes cause come before them.", "wycliffe": "Thi princes ben vnfeithful, the felowis of theuys; alle louen yiftis, suen meedis; thei demen not to a fadirles child, and the cause of a widewe entrith not to hem.", "rotherham": "Thy rulers, are unruly, and companions of thieves, Every one of the people, loveth a bribe, and runneth after rewards,—The fatherless, they do not vindicate, And, the plea of the widow, reacheth them not.", "darby": "thy princes are rebellious, and companions of thieves; every one loveth presents, and hunteth after rewards; they judge not the fatherless, and the cause of the widow cometh not unto them.", "twenty": "", "jps": "Thy princes are rebellious, and companions of thieves; every one loveth bribes, and followeth after rewards; they judge not the fatherless, neither doth the cause of the widow come unto them.", "acv": "Thy rulers are rebellious, and companions of thieves. Everyone loves bribes, and follows after rewards. They judge not the fatherless, nor does the cause of the widow come to them.", "anderson": "", "haweis": "", "noyes": "Thy princes are faithless, companions of thieves; Every one of them loveth gifts, and seeketh rewards; They render not justice to the fatherless, And the cause of the widow cometh not before them.", "webster": "Thy princes [are] rebellious, and companions of thieves: every one loveth gifts, and followeth after rewards: they judge not the fatherless, neither doth the cause of the widow come to them.", "vulgate": "principes tui infideles socii furum omnes diligunt munera sequuntur retributiones pupillo non iudicant et causa viduae non ingreditur ad eos;", "brenton": "Thy princes are rebellious, companions of thieves, loving bribes, seeking after rewards; not pleading for orphans, and not heeding the cause of widows."}}, {"v": 24, "ref": "1:24", "o": "לָ/כֵ֗ן נְאֻ֤ם הָֽ/אָדוֹן֙ יְהוָ֣ה צְבָא֔וֹת אֲבִ֖יר יִשְׂרָאֵ֑ל ה֚וֹי אֶנָּחֵ֣ם מִ/צָּרַ֔/י וְ/אִנָּקְמָ֖ה מֵ/אוֹיְבָֽ/י", "en": {"kjv": "Therefore saith the Lord, the Lord of hosts, the mighty One of Israel, Ah, I will ease me of mine adversaries, and avenge me of mine enemies:", "web": "Therefore the Lord, Yahweh of Armies, the Mighty One of Israel, says: “Ah, I will get relief from my adversaries, and avenge myself on my enemies;", "bsb": "Therefore the Lord GOD of Hosts, the Mighty One of Israel, declares: “Ah, I will be relieved of My foes and avenge Myself on My enemies.", "asv": "Therefore saith the Lord, Jehovah of hosts, the Mighty One of Israel, Ah, I will ease me of mine adversaries, and avenge me of mine enemies;", "ylt": "Therefore--the affirmation of the Lord--Jehovah of Hosts, the Mighty One of Israel: Ah, I am eased of Mine adversaries, And I am avenged of Mine enemies,", "dra": "Therefore saith the Lord the God of hosts, the mighty one of Israel: Ah! I will comfort myself over my adversaries: and I will be revenged of my enemies.", "bbe": "For this reason the Lord, the Lord of armies, the Strong One of Israel, has said, I will put an end to my haters, and send punishment on those who are against me;", "geneva": "Therefore sayth the Lord God of hostes, the mightie one of Israel, Ah, I will ease me of mine aduersaries, and auenge me of mine enemies.", "wycliffe": "For this thing, seith the Lord God of oostis, the stronge of Israel, Alas! Y schal be coumfortid on myn enemyes, and Y schal be vengid on myn enemyes.", "rotherham": "Therefore, Declareth the Lord Yahweh of hosts, The Mighty One of Israel,—Alas! I must appease me on mine adversaries, I must avenge me on mine enemies", "darby": "Therefore saith the Lord, Jehovah of hosts, the Mighty One of Israel: Ah! I will ease me of mine adversaries, and avenge me of mine enemies.", "twenty": "", "jps": "Therefore saith the L-rd, HaShem of hosts, the Mighty One of Israel: Ah, I will ease Me of Mine adversaries, and avenge Me of Mine enemies;", "acv": "Therefore says the Lord, Jehovah of hosts, the Mighty One of Israel, Ah, I will ease me of my adversaries, and avenge me of my enemies.", "anderson": "", "haweis": "", "noyes": "Wherefore, thus saith the Lord, Jehovah of hosts, the Mighty One of Israel: Ha! I will ease me of mine adversaries, And avenge me of mine enemies.", "webster": "Therefore saith the Lord, the LORD of hosts, the mighty One of Israel, Ah, I will ease me of my adversaries, and avenge me of my enemies:", "vulgate": "propter hoc ait Dominus exercituum Fortis Israhel heu consolabor super hostibus meis et vindicabor de inimicis meis;", "brenton": "Therefore thus saith the Lord, the Lord of hosts, Woe to the mighty men of Israel; for my wrath shall not cease against mine adversaries, and I will execute judgment on mine enemies."}}, {"v": 25, "ref": "1:25", "o": "וְ/אָשִׁ֤יבָה יָדִ/י֙ עָלַ֔יִ/ךְ וְ/אֶצְרֹ֥ף כַּ/בֹּ֖ר סִיגָ֑יִ/ךְ וְ/אָסִ֖ירָה כָּל בְּדִילָֽיִ/ךְ", "en": {"kjv": "And I will turn my hand upon thee, and purely purge away thy dross, and take away all thy tin:", "web": "and I will turn my hand on you, thoroughly purge away your dross, and will take away all your tin.", "bsb": "I will turn My hand against you; I will thoroughly purge your dross; I will remove all your impurities.", "asv": "and I will turn my hand upon thee, and thoroughly purge away thy dross, and will take away all thy tin;", "ylt": "And I turn back My hand upon thee, And I refine as purity thy dross, And I turn aside all thy tin,", "dra": "And I will turn my hand to thee, and I will clean purge away thy dross, and I will take away all thy tin.", "bbe": "And my hand will again be on you, washing away what is unclean as with soap, and taking away all your false metal;", "geneva": "Then I will turne mine hand vpon thee, and burne out thy drosse, till it be pure, and take away all thy tinne.", "wycliffe": "And Y schal turne myn hond to thee, and Y schal sethe out thi filthe to the cleene, and Y schal do awei al thi tyn.", "rotherham": "That I may turn my hand against thee, And smelt away, as with potash, thy dross, And remove all thine alloy;", "darby": "And I will turn my hand upon thee, and will thoroughly purge away thy dross, and take away all thine alloy;", "twenty": "", "jps": "And I will turn My hand upon thee, and purge away thy dross as with lye, and will take away all thine alloy;", "acv": "And I will turn my hand upon thee, and thoroughly purge away thy dross, and will take away all thy tin.", "anderson": "", "haweis": "", "noyes": "And I will again turn my hand toward thee, And wholly purge away thy dross, And take away all thy alloy.", "webster": "And I will turn my hand upon thee, and thoroughly purge away thy dross, and take away all thy tin:", "vulgate": "et convertam manum meam ad te et excoquam ad purum scoriam tuam et auferam omne stagnum tuum;", "brenton": "And I will bring my hand upon thee, and purge thee completely, and I will destroy the rebellious, and will take away from thee all transgressors."}}, {"v": 26, "ref": "1:26", "o": "וְ/אָשִׁ֤יבָה שֹׁפְטַ֨יִ/ךְ֙ כְּ/בָ/רִ֣אשֹׁנָ֔ה וְ/יֹעֲצַ֖יִ/ךְ כְּ/בַ/תְּחִלָּ֑ה אַחֲרֵי כֵ֗ן יִקָּ֤רֵא לָ/ךְ֙ עִ֣יר הַ/צֶּ֔דֶק קִרְיָ֖ה נֶאֱמָנָֽה", "en": {"kjv": "And I will restore thy judges as at the first, and thy counsellors as at the beginning: afterward thou shalt be called, The city of righteousness, the faithful city.", "web": "I will restore your judges as at the first, and your counselors as at the beginning. Afterward you shall be called ‘The city of righteousness, a faithful town.’", "bsb": "I will restore your judges as at first, and your counselors as at the beginning. After that you will be called the City of Righteousness, the Faithful City.”", "asv": "and I will restore thy judges as at the first, and thy counsellors as at the beginning: afterward thou shalt be called The city of righteousness, a faithful town.", "ylt": "And I give back thy judges as at the first, And thy counsellors as in the beginning, After this thou art called, `A city of righteousness--a faithful city.'", "dra": "And I will restore thy judges as they were before, and thy counsellors as of old. After this thou shalt be called the city of the just, a faithful city.", "bbe": "And I will give you judges again as at the first, and wise guides as in the past; then you will be named, The Town of Righteousness, the true town.", "geneva": "And I will restore thy iudges as at the first, and thy counsellers as at the beginning: afterward shalt thou be called a citie of righteousnes, and a faithfull citie.", "wycliffe": "And Y schal restore thi iuges, as thei weren bifor to, and thi counselours, as in elde tyme. Aftir these thingis thou schalt be clepid the citee of the riytful, a feithful citee.", "rotherham": "That I may restore thy Judges as at the first, and thy Counsellors as at the beginning,—After that, shalt thou be called Righteous citadel, Trusty city,—", "darby": "and I will restore thy judges as at the first, and thy counsellors as at the beginning. Afterwards thou shalt be called, Town of righteousness, Faithful city.", "twenty": "", "jps": "And I will restore thy judges as at the first, and thy counsellors as at the beginning; afterward thou shalt be called The city of righteousness, the faithful city.", "acv": "And I will restore thy judges as at the first, and thy counselors as at the beginning. Afterward thou shall be called the city of righteousness, a faithful town.", "anderson": "", "haweis": "", "noyes": "And I will restore thee judges, as at the first, And counsellors, as at the beginning. Then shalt thou be called the city of righteousness, the faithful city.", "webster": "And I will restore thy judges as at the first, and thy counselors as at the beginning: afterward thou shalt be called, The city of righteousness, the faithful city.", "vulgate": "et restituam iudices tuos ut fuerunt prius et consiliarios tuos sicut antiquitus post haec vocaberis civitas iusti urbs fidelis;", "brenton": "And I will establish thy judges as before, and thy counsellors as at the beginning: and afterward thou shalt be called the city of righteousness, the faithful mother-city of Sion."}}, {"v": 27, "ref": "1:27", "o": "צִיּ֖וֹן בְּ/מִשְׁפָּ֣ט תִּפָּדֶ֑ה וְ/שָׁבֶ֖י/הָ בִּ/צְדָקָֽה", "en": {"kjv": "Zion shall be redeemed with judgment, and her converts with righteousness.", "web": "Zion shall be redeemed with justice, and her converts with righteousness.", "bsb": "Zion will be redeemed with justice, her repentant ones with righteousness.", "asv": "Zion shall be redeemed with justice, and her converts with righteousness.", "ylt": "Zion in judgment is redeemed, And her captivity in righteousness.", "dra": "Sion shall be redeemed in judgment, and they shall bring her back in justice.", "bbe": "Upright acts will be the price of Zion's forgiveness, and by righteousness will men be living there.", "geneva": "Zion shall be redeemed in iudgement, and they that returne in her, in iustice.", "wycliffe": "Sion schal be ayen bouyt in dom, and thei schulen bringe it ayen in to riytfulnesse;", "rotherham": "Zion, with justice shall be redeemed,—And her returning ones, with righteousness;", "darby": "Zion shall be redeemed with judgment, and they that return of her with righteousness.", "twenty": "", "jps": "Zion shall be redeemed with justice, and they that return of her with righteousness.", "acv": "Zion shall be redeemed with justice, and her converts with righteousness.", "anderson": "", "haweis": "", "noyes": "Through justice shall Zion be delivered, And her reformed sons through righteousness.", "webster": "Zion shall be redeemed with judgment, and her converts with righteousness.", "vulgate": "Sion in iudicio redimetur et reducent eam in iustitia;", "brenton": "For her captives shall be saved with judgment, and with mercy."}}, {"v": 28, "ref": "1:28", "o": "וְ/שֶׁ֧בֶר פֹּשְׁעִ֛ים וְ/חַטָּאִ֖ים יַחְדָּ֑ו וְ/עֹזְבֵ֥י יְהוָ֖ה יִכְלֽוּ", "en": {"kjv": "And the destruction of the transgressors and of the sinners shall be together, and they that forsake the Lord shall be consumed.", "web": "But the destruction of transgressors and sinners shall be together, and those who forsake Yahweh shall be consumed.", "bsb": "But rebels and sinners will together be shattered, and those who forsake the LORD will perish.", "asv": "But the destruction of transgressors and sinners shall be together, and they that forsake Jehovah shall be consumed.", "ylt": "And the destruction of transgressors and sinners is together, And those forsaking Jehovah are consumed.", "dra": "And he shall destroy the wicked, and the sinners together: and they that have forsaken the Lord, shall be consumed.", "bbe": "But a common destruction will overtake sinners and evil-doers together, and those who have gone away from the Lord will be cut off.", "geneva": "And the destruction of the transgressers and of the sinners shalbe together: and they that forsake the Lord, shalbe consumed.", "wycliffe": "and God schal al to-breke cursid men and synneris togidere, and thei that forsoken the Lord, schulen be wastid.", "rotherham": "And the downfall of transgressors and sinners, shall be, together,—And, they who forsake Yahweh, shall be brought to an end;", "darby": "But the ruin of the transgressors and of the sinners [shall be] together; and they that forsake Jehovah shall be consumed.", "twenty": "", "jps": "But the destruction of the transgressors and the sinners shall be together, and they that forsake HaShem shall be consumed.", "acv": "But the destruction of transgressors and sinners shall be together, and those who forsake Jehovah shall be consumed.", "anderson": "", "haweis": "", "noyes": "But destruction shall fall at once on the rebels and sinners; Yea, they that forsake Jehovah shall be consumed.", "webster": "And the destruction of the transgressors and of the sinners [shall be] together, and they that forsake the LORD shall be consumed.", "vulgate": "et conteret scelestos et peccatores simul et qui dereliquerunt Dominum consumentur;", "brenton": "And the transgressors and the sinners shall be crushed together, and they that forsake the Lord shall be utterly consumed."}}, {"v": 29, "ref": "1:29", "o": "כִּ֣י יֵבֹ֔שׁוּ מֵ/אֵילִ֖ים אֲשֶׁ֣ר חֲמַדְתֶּ֑ם וְ/תַ֨חְפְּר֔וּ מֵ/הַ/גַּנּ֖וֹת אֲשֶׁ֥ר בְּחַרְתֶּֽם", "en": {"kjv": "For they shall be ashamed of the oaks which ye have desired, and ye shall be confounded for the gardens that ye have chosen.", "web": "For they shall be ashamed of the oaks which you have desired, and you shall be confounded for the gardens that you have chosen.", "bsb": "Surely you will be ashamed of the sacred oaks in which you have delighted; you will be embarrassed by the gardens that you have chosen.", "asv": "For they shall be ashamed of the oaks which ye have desired, and ye shall be confounded for the gardens that ye have chosen.", "ylt": "For men are ashamed because of the oaks That ye have desired, And ye are confounded because of the gardens That ye have chosen.", "dra": "For they shall be confounded for the idols, to which they have sacrificed: and you shall be ashamed of the gardens which you have chosen.", "bbe": "For you will be put to shame because of the trees of your desire, and because of the gardens of your pleasure.", "geneva": "For they shalbe confounded for the okes, which ye haue desired, and ye shall be ashamed of the gardens, that ye haue chosen.", "wycliffe": "For thei schulen be aschamed of idols, to whiche thei maden sacrifice; and ye shulen be aschamid on the orcherdis, whiche ye chesiden.", "rotherham": "For they shall turn pale on account of the oaks which ye desired,—And ye shall blush on account of the gardens which ye had chosen;", "darby": "For they shall be ashamed of the terebinths that ye have desired, and ye shall blush for the gardens that ye have chosen.", "twenty": "", "jps": "For they shall be ashamed of the terebinths which ye have desired, and ye shall be confounded for the gardens that ye have chosen.", "acv": "For they shall be ashamed of the oaks which ye have desired, and ye shall be confounded for the gardens that ye have chosen.", "anderson": "", "haweis": "", "noyes": "For ye shall be ashamed of the terebinths in which ye delighted; Ye shall blush for the gardens which ye loved;", "webster": "For they shall be ashamed of the oaks which ye have desired, and ye shall be confounded for the gardens that ye have chosen.", "vulgate": "confundentur enim ab idolis quibus sacrificaverunt et erubescetis super hortis quos elegeratis;", "brenton": "For they shall be ashamed of their idols, which they delighted in, and they are made ashamed of the gardens which they coveted."}}, {"v": 30, "ref": "1:30", "o": "כִּ֣י תִֽהְי֔וּ כְּ/אֵלָ֖ה נֹבֶ֣לֶת עָלֶ֑/הָ וּֽ/כְ/גַנָּ֔ה אֲשֶׁר מַ֖יִם אֵ֥ין לָֽ/הּ", "en": {"kjv": "For ye shall be as an oak whose leaf fadeth, and as a garden that hath no water.", "web": "For you shall be as an oak whose leaf fades, and as a garden that has no water.", "bsb": "For you will become like an oak whose leaves are withered, like a garden without water.", "asv": "For ye shall be as an oak whose leaf fadeth, and as a garden that hath no water.", "ylt": "For ye are as an oak whose leaf is fading, And as a garden that hath no water.", "dra": "When you shall be as an oak with the leaves falling off, and as a garden without water.", "bbe": "For you will be like a tree whose leaves have become dry, and like a garden without water.", "geneva": "For ye shalbe as an oke, whose leafe fadeth: and as a garden that hath no water.", "wycliffe": "Whanne ye schulen be as an ook, whanne the leeues fallen doun, and as an orcherd with out watir.", "rotherham": "For ye shall be as an oak with its leaf faded, And as a garden that hath no, water;", "darby": "For ye shall be as a terebinth whose leaf fadeth, and as a garden that hath no water.", "twenty": "", "jps": "For ye shall be as a terebinth whose leaf fadeth, and as a garden that hath no water.", "acv": "For ye shall be as an oak whose leaf fades, and as a garden that has no water.", "anderson": "", "haweis": "", "noyes": "And ye shall be as a terebinth-tree whose leaves are withered, And as a garden in which is no water.", "webster": "For ye shall be as an oak whose leaf fadeth, and as a garden that hath no water.", "vulgate": "cum fueritis velut quercus defluentibus foliis et velut hortus absque aqua;", "brenton": "For they shall be as a turpentine tree that has cast its leaves, and as a garden that has no water."}}, {"v": 31, "ref": "1:31", "o": "וְ/הָיָ֤ה הֶ/חָסֹן֙ לִ/נְעֹ֔רֶת וּ/פֹעֲל֖/וֹ לְ/נִיצ֑וֹץ וּ/בָעֲר֧וּ שְׁנֵי/הֶ֛ם יַחְדָּ֖ו וְ/אֵ֥ין מְכַבֶּֽה", "en": {"kjv": "And the strong shall be as tow, and the maker of it as a spark, and they shall both burn together, and none shall quench them.", "web": "The strong will be like tinder, and his work like a spark. They will both burn together, and no one will quench them.”", "bsb": "The strong man will become tinder and his work will be a spark; both will burn together, with no one to quench the flames.", "asv": "And the strong shall be as tow, and his work as a spark; and they shall both burn together, and none shall quench them.", "ylt": "And the strong hath been for tow, And his work for a spark, And burned have both of them together, And there is none quenching!", "dra": "And your strength shall be as the ashes of tow, and your work as a spark: and both shall burn together, and there shall be none to quench it.", "bbe": "And the strong will be as food for the fire, and his work as a flame; and they will be burned together, with no one to put out the fire.", "geneva": "And the strong shall be as towe, and the maker thereof, as a sparke: and they shall both burne together, and none shall quench them.", "wycliffe": "And youre strengthe schal be as a deed sparcle of bonys, `ether of herdis of flex, and youre werk schal be as a quyk sparcle; and euer either schal be brent togidere, and noon schal be that schal quenche.", "rotherham": "Then shall the strong one become tow, And his work a spark,—And they shall both blaze together And there be none to quench the fire.", "darby": "And the strong shall be for tow, and his work a spark; and they shall both burn together, and there shall be none to quench [them].", "twenty": "", "jps": "And the strong shall be as tow, and his work as a spark; and they shall both burn together, and none shall quench them.", "acv": "And the strong man shall be as flax, and his work as a spark. And they shall both burn together, and none shall quench them.", "anderson": "", "haweis": "", "noyes": "The strong shall become tow, And his work a spark of fire; Both shall burn together, And none shall quench them.", "webster": "And the strong shall be as tow, and the maker of it as a spark, and they shall both burn together, and none shall quench [them].", "vulgate": "et erit fortitudo vestra ut favilla stuppae et opus vestrum quasi scintilla et succendetur utrumque simul et non erit qui extinguat;", "brenton": "And their strength shall be as a thread of tow, and their works as sparks, and the transgressors and the sinners shall be burnt up together, and there shall be none to quench them."}}]}, {"c": 2, "verses": [{"v": 1, "ref": "2:1", "o": "הַ/דָּבָר֙ אֲשֶׁ֣ר חָזָ֔ה יְשַֽׁעְיָ֖הוּ בֶּן אָמ֑וֹץ עַל יְהוּדָ֖ה וִ/ירוּשָׁלִָֽם", "en": {"kjv": "The word that Isaiah the son of Amoz saw concerning Judah and Jerusalem.", "web": "This is what Isaiah the son of Amoz saw concerning Judah and Jerusalem.", "bsb": "This is the message that was revealed to Isaiah son of Amoz concerning Judah and Jerusalem:", "asv": "The word that Isaiah the son of Amoz saw concerning Judah and Jerusalem.", "ylt": "The thing that Isaiah son of Amoz hath seen concerning Judah and Jerusalem:", "dra": "The word that Isaiah the son of Amos saw, concerning Juda and Jerusalem.", "bbe": "The word which Isaiah, the son of Amoz, saw about Judah and Jerusalem.", "geneva": "The worde that Isaiah the sonne of Amoz sawe vpon Iudah and Ierusalem.", "wycliffe": "The word which Ysaie, the sone of Amos, siy on Juda and Jerusalem.", "rotherham": "That which Isaiah, son of Amoz saw in vision,—concerning Judah and Jerusalem.", "darby": "The word that Isaiah the son of Amoz saw concerning Judah and Jerusalem.", "twenty": "", "jps": "The word that Isaiah the son of Amoz saw concerning Judah and Jerusalem.", "acv": "The word that Isaiah the son of Amoz saw concerning Judah and Jerusalem.", "anderson": "", "haweis": "", "noyes": "The word, which was revealed to Isaiah, the son of Amoz, concerning Judah and Jerusalem.", "webster": "The word that Isaiah the son of Amoz saw concerning Judah and Jerusalem.", "vulgate": "verbum quod vidit Isaias filius Amos super Iudam et Hierusalem;", "brenton": "The word which came to Esaias the son of Amos concerning Judea, and concerning Jerusalem."}}, {"v": 2, "ref": "2:2", "o": "וְ/הָיָ֣ה בְּ/אַחֲרִ֣ית הַ/יָּמִ֗ים נָכ֨וֹן יִֽהְיֶ֜ה הַ֤ר בֵּית יְהוָה֙ בְּ/רֹ֣אשׁ הֶ/הָרִ֔ים וְ/נִשָּׂ֖א מִ/גְּבָע֑וֹת וְ/נָהֲר֥וּ אֵלָ֖י/ו כָּל הַ/גּוֹיִֽם", "en": {"kjv": "And it shall come to pass in the last days, that the mountain of the Lord’s house shall be established in the top of the mountains, and shall be exalted above the hills; and all nations shall flow unto it.", "web": "It shall happen in the latter days, that the mountain of Yahweh’s house shall be established on the top of the mountains, and shall be raised above the hills; and all nations shall flow to it.", "bsb": "In the last days the mountain of the house of the LORD will be established as the chief of the mountains; it will be raised above the hills, and all nations will stream to it.", "asv": "And it shall come to pass in the latter days, that the mountain of Jehovah’s house shall be established on the top of the mountains, and shall be exalted above the hills; and all nations shall flow unto it.", "ylt": "And it hath come to pass, In the latter end of the days, Established is the mount of Jehovah's house, Above the top of the mounts, And it hath been lifted up above the heights, And flowed unto it have all the nations.", "dra": "And in the last days the mountain of the house of the Lord shall be prepared on the top of mountains, and it shall be exalted above the hills, and all nations shall flow unto it.", "bbe": "And it will come about in the last days, that the mountain of the Lord will be placed on the top of the mountains, and be lifted up over the hills; and all nations will come to it.", "geneva": "It shall be in the last dayes, that the mountaine of the house of the Lord shalbe prepared in the top of the mountaines, and shall be exalted aboue the hilles, and all nations shall flowe vnto it.", "wycliffe": "And in the laste daies the hil of the hous of the Lord schal be maad redi in the cop of hillis, and schal be reisid aboue litle hillis. And alle hethene men schulen flowe to hym;", "rotherham": "But it shall come to pass, in the afterpart of the days, That the mountain of the house of Yahweh Shall be, set up, as the head of the mountains, And be exalted above the hills,—And all the nations, shall stream thereunto;", "darby": "And it shall come to pass in the end of days, [that] the mountain of Jehovah's house shall be established on the top of the mountains, and shall be lifted up above the hills; and all the nations shall flow unto it.", "twenty": "", "jps": "And it shall come to pass in the end of days, that the mountain of HaShem'S house shall be established as the top of the mountains, and shall be exalted above the hills; and all nations shall flow unto it.", "acv": "And it shall come to pass in the latter days, that the mountain of Jehovah's house shall be established on the top of the mountains, and shall be exalted above the hills, and all nations shall flow to it.", "anderson": "", "haweis": "", "noyes": "It shall come to pass in the last days, That the mountain of the house of Jehovah shall be established at the head of the mountains, And exalted above the hills; And all nations shall flow unto it.", "webster": "And it shall come to pass in the last days, [that] the mount of the LORD'S house shall be established on the top of the mountains, and shall be exalted above the hills; and all nations shall flow to it.", "vulgate": "et erit in novissimis diebus praeparatus mons domus Domini in vertice montium et elevabitur super colles et fluent ad eum omnes gentes;", "brenton": "For in the last days the mountain of the Lord shall be glorious, and the house of God shall be on the top of the mountains, and it shall be exalted above the hills; and all nations shall come to it."}}, {"v": 3, "ref": "2:3", "o": "וְֽ/הָלְכ֞וּ עַמִּ֣ים רַבִּ֗ים וְ/אָמְרוּ֙ לְכ֣וּ וְ/נַעֲלֶ֣ה אֶל הַר יְהוָ֗ה אֶל בֵּית֙ אֱלֹהֵ֣י יַעֲקֹ֔ב וְ/יֹרֵ֨/נוּ֙ מִ/דְּרָכָ֔י/ו וְ/נֵלְכָ֖ה בְּ/אֹרְחֹתָ֑י/ו כִּ֤י מִ/צִּיּוֹן֙ תֵּצֵ֣א תוֹרָ֔ה וּ/דְבַר יְהוָ֖ה מִ/ירוּשָׁלִָֽם", "en": {"kjv": "And many people shall go and say, Come ye, and let us go up to the mountain of the Lord, to the house of the God of Jacob; and he will teach us of his ways, and we will walk in his paths: for out of Zion shall go forth the law, and the word of the Lord from Jerusalem.", "web": "Many peoples shall go and say, “Come, let’s go up to the mountain of Yahweh, to the house of the God of Jacob; and he will teach us of his ways, and we will walk in his paths.” For out of Zion the law shall go out, and Yahweh’s word from Jerusalem.", "bsb": "And many peoples will come and say: “Come, let us go up to the mountain of the LORD, to the house of the God of Jacob. He will teach us His ways so that we may walk in His paths.” For the law will go forth from Zion, and the word of the LORD from Jerusalem.", "asv": "And many peoples shall go and say, Come ye, and let us go up to the mountain of Jehovah, to the house of the God of Jacob; and he will teach us of his ways, and we will walk in his paths: for out of Zion shall go forth the law, and the word of Jehovah from Jerusalem.", "ylt": "And gone have many peoples and said, `Come, and we go up unto the mount of Jehovah, Unto the house of the God of Jacob, And He doth teach us of His ways, And we walk in His paths, For from Zion goeth forth a law, And a word of Jehovah from Jerusalem.", "dra": "And many people shall go, and say: Come and let us go up to the mountain of the Lord, and to the house of the God of Jacob, and he will teach us his ways, and we will walk in his paths: for the law shall come forth from Sion, and the word of the Lord from Jerusalem.", "bbe": "And the peoples will say, Come, and let us go up to the mountain of the Lord, to the house of the God of Jacob: and he will give us knowledge of his ways, and we will be guided by his word; for out of Zion the law will go out, and the word of the Lord from Jerusalem.", "geneva": "And many people shall go, and say, Come, and let vs go vp to the mountaine of the Lord, to the house of the God of Iaakob, and hee will teach vs his wayes, and we will walke in his paths: for the Lawe shall go foorth of Zion, and the worde of the Lord from Ierusalem,", "wycliffe": "and many puplis schulen go, and schulen seie, Come ye, stie we to the hil of the Lord, and to the hous of God of Jacob; and he schal teche vs hise weies, and we schulen go in the pathis of hym. For whi the lawe schal go out of Syon, and the word of the Lord fro Jerusalem.", "rotherham": "And many peoples shall go and say—Come ye, and let us ascend Unto the mountain of Yahweh Unto the house of the God of Jacob, That he may teach us of his ways, And we may walk in his paths,—For, out of Zion, shall go forth a law, And the word of Yahweh out of Jerusalem;", "darby": "And many peoples shall go and say, Come, and let us go up to the mountain of Jehovah, to the house of theGod of Jacob; and he will teach us of his ways, and we will walk in his paths. For out of Zion shall go forth the law, and Jehovah's word from Jerusalem.", "twenty": "", "jps": "And many peoples shall go and say: 'Come ye, and let us go up to the mountain of HaShem, to the house of the G-d of Jacob; and He will teach us of His ways, and we will walk in His paths.' For out of Zion shall go forth the law, and the word of HaShem from Jerusalem.", "acv": "And many peoples shall go and say, Come ye, and let us go up to the mountain of Jehovah, to the house of the God of Jacob, and he will teach us of his ways, and we will walk in his paths. For out of Zion shall go forth the law, and the word of Jehovah from Jerusalem.", "anderson": "", "haweis": "", "noyes": "And many kingdoms shall go, and shall say, \"Come, let us go to the mountain of Jehovah, To the house of the God of Jacob, That he may teach us his ways, And that we may walk in his paths!\" For from Zion shall go forth a law, And the word of Jehovah from Jerusalem.", "webster": "And many people shall go and say, Come ye, and let us go up to the mountain of the LORD, to the house of the God of Jacob; and he will teach us of his ways, and we will walk in his paths: for out of Zion shall go forth the law, and the word of the LORD from Jerusalem.", "vulgate": "et ibunt populi multi et dicent venite et ascendamus ad montem Domini et ad domum Dei Iacob et docebit nos vias suas et ambulabimus in semitis eius quia de Sion exibit lex et verbum Domini de Hierusalem;", "brenton": "And many nations shall go and say, Come, and let us go up to the mountain of the Lord, and to the house of the God of Jacob; and he will tell us his way, and we will walk in it: for out of Sion shall go forth the law, and the word of the Lord out of Jerusalem."}}, {"v": 4, "ref": "2:4", "o": "וְ/שָׁפַט֙ בֵּ֣ין הַ/גּוֹיִ֔ם וְ/הוֹכִ֖יחַ לְ/עַמִּ֣ים רַבִּ֑ים וְ/כִתְּת֨וּ חַרְבוֹתָ֜/ם לְ/אִתִּ֗ים וַ/חֲנִיתֽוֹתֵי/הֶם֙ לְ/מַזְמֵר֔וֹת לֹא יִשָּׂ֨א ג֤וֹי אֶל גּוֹי֙ חֶ֔רֶב וְ/לֹא יִלְמְד֥וּ ע֖וֹד מִלְחָמָֽה", "en": {"kjv": "And he shall judge among the nations, and shall rebuke many people: and they shall beat their swords into plowshares, and their spears into pruninghooks: nation shall not lift up sword against nation, neither shall they learn war any more.", "web": "He will judge between the nations, and will decide concerning many peoples; and they shall beat their swords into plowshares, and their spears into pruning hooks. Nation shall not lift up sword against nation, neither shall they learn war any more.", "bsb": "Then He will judge between the nations and arbitrate for many peoples. They will beat their swords into plowshares and their spears into pruning hooks. Nation will no longer take up the sword against nation, nor train anymore for war.", "asv": "And he will judge between the nations, and will decide concerning many peoples; and they shall beat their swords into plowshares, and their spears into pruning-hooks; nation shall not lift up sword against nation, neither shall they learn war any more.", "ylt": "And He hath judged between the nations, And hath given a decision to many peoples, And they have beat their swords to ploughshares, And their spears to pruning-hooks, Nation doth not lift up sword unto nation, Nor do they learn any more--war.", "dra": "And he shall judge the Gentiles, and rebuke many people: and they shall turn their swords into ploughshares, and their spears into sickles: nation shall not lift up sword against nation, neither shall they be exercised any more to war.", "bbe": "And he will be the judge between the nations, and the peoples will be ruled by his decisions: and their swords will be turned into plough-blades, and their spears into vine-knives: no longer will the nations be turning their swords against one another, and the knowledge of war will be gone for ever.", "geneva": "And he shall iudge among the nations, and rebuke many people: they shall breake their swords also into mattocks, and their speares into siethes: nation shall not lift vp a sworde against nation, neither shall they learne to fight any more.", "wycliffe": "And he schal deme hethene men, and he schal repreue many puplis; and thei schulen welle togidere her swerdes in to scharris, and her speris in to sikelis, ether sithes; folk schal no more reise swerd ayens folk, and thei schulen no more be exercisid to batel.", "rotherham": "And he will judge between the nations, And be umpire to many peoples,—And they will beat their swords into ploughshares and their spears into pruning-hooks, Nation—against nation, shall not lift up sword, Neither shall they learn any more to make war,", "darby": "And he shall judge among the nations, and shall reprove many peoples; and they shall forge their swords into ploughshares, and their spears into pruning-knives: nation shall not lift up sword against nation, neither shall they learn war any more.", "twenty": "", "jps": "And He shall judge between the nations, and shall decide for many peoples; and they shall beat their swords into plowshares, and their spears into pruninghooks; nation shall not lift up sword against nation, neither shall they learn war any more.", "acv": "And he will judge between the nations, and will decide concerning many peoples, and they shall beat their swords into plowshares, and their spears into pruning-hooks. Nation shall not lift up sword against nation, neither shall they learn war any more.", "anderson": "", "haweis": "", "noyes": "He shall be a judge of the nations, And an umpire of many kingdoms; And they shall beat their swords into ploughshares, And their spears into pruning-hooks; Nation shall not lift up the sword against nation, Neither shall they learn war any more.", "webster": "And he will judge among the nations, and will rebuke many people: and they shall beat their swords into plow-shares, and their spears into pruning-hooks: nation shall not lift up sword against nation, neither shall they learn war any more.", "vulgate": "et iudicabit gentes et arguet populos multos et conflabunt gladios suos in vomeres et lanceas suas in falces non levabit gens contra gentem gladium nec exercebuntur ultra ad proelium;", "brenton": "And he shall judge among the nations, and shall rebuke many people: and they shall beat their swords into plow-shares, and their spears into sickles: and nation shall not take up sword against nation, neither shall they learn to war any more."}}, {"v": 5, "ref": "2:5", "o": "בֵּ֖ית יַעֲקֹ֑ב לְכ֥וּ וְ/נֵלְכָ֖ה בְּ/א֥וֹר יְהוָֽה", "en": {"kjv": "O house of Jacob, come ye, and let us walk in the light of the Lord.", "web": "House of Jacob, come, and let us walk in the light of Yahweh.", "bsb": "Come, O house of Jacob, let us walk in the light of the LORD.", "asv": "O house of Jacob, come ye, and let us walk in the light of Jehovah.", "ylt": "O house of Jacob, come, And we walk in the light of Jehovah.'", "dra": "O house of Jacob, come ye, and let us walk in the light of the Lord.", "bbe": "O family of Jacob, come, and let us go in the light of the Lord.", "geneva": "O house of Iaakob, come ye, and let vs walke in the Lawe of the Lord.", "wycliffe": "Come ye, the hous of Jacob, and go we in the liyt of the Lord.", "rotherham": "O house of Jacob! come ye and let us walk in the light of Yahweh.", "darby": "House of Jacob, come ye, and let us walk in the light of Jehovah.", "twenty": "", "jps": "O house of Jacob, come ye, and let us walk in the light of HaShem.", "acv": "O house of Jacob, come ye, and let us walk in the light of Jehovah.", "anderson": "", "haweis": "", "noyes": "O house of Jacob, come ye, And let us walk in the light of Jehovah!", "webster": "O house of Jacob, come ye, and let us walk in the light of the LORD.", "vulgate": "domus Iacob venite et ambulemus in lumine Domini;", "brenton": "And now, O house of Jacob, come, and let us walk in the light of the Lord."}}, {"v": 6, "ref": "2:6", "o": "כִּ֣י נָטַ֗שְׁתָּה עַמְּ/ךָ֙ בֵּ֣ית יַעֲקֹ֔ב כִּ֤י מָלְאוּ֙ מִ/קֶּ֔דֶם וְ/עֹֽנְנִ֖ים כַּ/פְּלִשְׁתִּ֑ים וּ/בְ/יַלְדֵ֥י נָכְרִ֖ים יַשְׂפִּֽיקוּ", "en": {"kjv": "Therefore thou hast forsaken thy people the house of Jacob, because they be replenished from the east, and are soothsayers like the Philistines, and they please themselves in the children of strangers.", "web": "For you have forsaken your people, the house of Jacob, because they are filled from the east, with those who practice divination like the Philistines, and they clasp hands with the children of foreigners.", "bsb": "For You have abandoned Your people, the house of Jacob, because they are filled with influences from the east; they are soothsayers like the Philistines; they strike hands with the children of foreigners.", "asv": "For thou hast forsaken thy people the house of Jacob, because they are filled with customs from the east, and are soothsayers like the Philistines, and they strike hands with the children of foreigners.", "ylt": "For Thou hast left Thy people, the house of Jacob. For they have been filled from the east, And are sorcerers like the Philistines, And with the children of strangers strike hands.", "dra": "For thou hast cast off thy people, the house of Jacob: because they are filled as in times past, and have had soothsayers as the Philistines, and have adhered to strange children.", "bbe": "For you, O Lord, have given up your people, the family of Jacob, because they are full of the evil ways of the east, and make use of secret arts like the Philistines, and are friends with the children of strange countries.", "geneva": "Surely thou hast forsaken thy people, the house of Iaakob, because they are full of the East maners, and are sorcerers as the Philistims, and abound with strange children.", "wycliffe": "Forsothe thou hast cast awei thi puple, the hous of Jacob, for thei ben fillid as sum tyme bifore; and thei hadden false dyuynouris bi the chiteryng of briddis, as Filisteis, and thei cleuyden to alien children.", "rotherham": "Therefore hast thou abandoned thy people the house of Jacob, Because they have become full of the East, And use hidden arts like the Philistines,—And with the children of foreigners, strike hands;—", "darby": "For thou hast cast off thy people, the house of Jacob, because they are filled [with what comes] from the east, and use auguries like the Philistines, and ally themselves with the children of foreigners.", "twenty": "", "jps": "For Thou hast forsaken Thy people the house of Jacob; for they are replenished from the east, and with soothsayers like the Philistines, and they please themselves in the brood of aliens.", "acv": "For thou have forsaken thy people the house of Jacob, because they are filled with things from the east, and are soothsayers like the Philistines. And they strike hands with the children of foreigners.", "anderson": "", "haweis": "", "noyes": "For thou hast forsaken thy people, the house of Jacob, Because they are full of the East, And are sorcerers, like the Philistines, And strike hands with a foreign race!", "webster": "Therefore thou hast forsaken thy people the house of Jacob, because they are replenished from the east, and [are] sooth-sayers like the Philistines, and they please themselves in the children of strangers.", "vulgate": "proiecisti enim populum tuum domum Iacob quia repleti sunt ut olim et augures habuerunt ut Philisthim et pueris alienis adheserunt;", "brenton": "For he has forsaken his people the house of Israel, because their land is filled as at the beginning with divinations, as the land of the Philistines, and many strange children were born to them."}}, {"v": 7, "ref": "2:7", "o": "וַ/תִּמָּלֵ֤א אַרְצ/וֹ֙ כֶּ֣סֶף וְ/זָהָ֔ב וְ/אֵ֥ין קֵ֖צֶה לְ/אֹצְרֹתָ֑י/ו וַ/תִּמָּלֵ֤א אַרְצ/וֹ֙ סוּסִ֔ים וְ/אֵ֥ין קֵ֖צֶה לְ/מַרְכְּבֹתָֽי/ו", "en": {"kjv": "Their land also is full of silver and gold, neither is there any end of their treasures; their land is also full of horses, neither is there any end of their chariots:", "web": "Their land is full of silver and gold, neither is there any end of their treasures. Their land also is full of horses, neither is there any end of their chariots.", "bsb": "Their land is full of silver and gold, with no limit to their treasures; their land is full of horses, with no limit to their chariots.", "asv": "And their land is full of silver and gold, neither is there any end of their treasures; their land also is full of horses, neither is there any end of their chariots.", "ylt": "And its land is full of silver and gold, And there is no end to its treasures, And its land is full of horses, And there is no end to its chariots,", "dra": "Their land is filled with silver and gold: and there is no end of their treasures.", "bbe": "And their land is full of silver and gold, and there is no end to their stores; their land is full of horses, and there is no end to their carriages.", "geneva": "Their land also was full of siluer and golde, and there was none ende of their treasures: and their land was full of horses, and their charets were infinite.", "wycliffe": "The lond is fillid with siluer and gold, and noon ende is of the tresouris therof; and the lond therof is fillid with horsis, and the foure horsid cartis therof ben vnnoumbrable.", "rotherham": "So that filled is their land with silver and gold, And there is no end to their treasures,—And filled is their land with horses, And there is no end to their chariots;", "darby": "And their land is full of silver and gold, and there is no end of their treasures: their land also is full of horses, and there is no end of their chariots.", "twenty": "", "jps": "Their land also is full of silver and gold, neither is there any end of their treasures; their land also is full of horses, neither is there any end of their chariots.", "acv": "And their land is full of silver and gold, neither is there any end of their treasures. Their land is also full of horses, neither is there any end of their chariots.", "anderson": "", "haweis": "", "noyes": "Their land is full of silver and gold, And there is no end to their treasures; Their land is full of horses, And there is no end to their chariots;", "webster": "Their land also is full of silver and gold, neither [is there any] end of their treasures; their land is also full of horses, neither [is there any] end of their chariots:", "vulgate": "repleta est terra argento et auro et non est finis thesaurorum eius;", "brenton": "For their land is filled with silver and gold, and there was no number of their treasures; their land also is filled with horses, and there was no number of chariots."}}, {"v": 8, "ref": "2:8", "o": "וַ/תִּמָּלֵ֥א אַרְצ֖/וֹ אֱלִילִ֑ים לְ/מַעֲשֵׂ֤ה יָדָי/ו֙ יִֽשְׁתַּחֲו֔וּ לַ/אֲשֶׁ֥ר עָשׂ֖וּ אֶצְבְּעֹתָֽי/ו", "en": {"kjv": "Their land also is full of idols; they worship the work of their own hands, that which their own fingers have made:", "web": "Their land also is full of idols. They worship the work of their own hands, that which their own fingers have made.", "bsb": "Their land is full of idols; they bow down to the work of their hands, to what their fingers have made.", "asv": "Their land also is full of idols; they worship the work of their own hands, that which their own fingers have made.", "ylt": "And its land is full of idols, To the work of its hands it boweth itself, To that which its fingers have made,", "dra": "And their land is filled with horses: and their chariots are innumerable. Their land also is full of idols: they have adored the work of their own hands, which their own fingers have made.", "bbe": "Their land is full of images; they give worship to the work of their hands, even to that which their fingers have made.", "geneva": "Their land also was full of idols: they worshipped the worke of their owne hands, which their owne fingers haue made.", "wycliffe": "And the lond therof is fillid with ydols, and thei worschipiden the werk of her hondis, which her fyngris maden;", "rotherham": "And filled is their land with idols,—To the work of their own hands, do they bow themselves down, To that which they made with their own fingers.", "darby": "And their land is full of idols; they bow themselves down to the work of their own hands, to that which their fingers have made.", "twenty": "", "jps": "Their land also is full of idols; every one worshippeth the work of his own hands, that which his own fingers have made.", "acv": "Their land is also full of idols. They worship the work of their own hands, that which their own fingers have made,", "anderson": "", "haweis": "", "noyes": "Their land is full of idols; They bow down to the work of their own hands, To that which their own fingers have made.", "webster": "Their land also is full of idols; they worship the work of their own hands, that which their own fingers have made:", "vulgate": "et repleta est terra eius equis et innumerabiles quadrigae eius et repleta est terra eius idolis opus manuum suarum adoraverunt quod fecerunt digiti eorum;", "brenton": "And the land is filled with abominations, even the works of their hands; and they have worshipped the works which their fingers made."}}, {"v": 9, "ref": "2:9", "o": "וַ/יִּשַּׁ֥ח אָדָ֖ם וַ/יִּשְׁפַּל אִ֑ישׁ וְ/אַל תִּשָּׂ֖א לָ/הֶֽם", "en": {"kjv": "And the mean man boweth down, and the great man humbleth himself: therefore forgive them not.", "web": "Man is brought low, and mankind is humbled; therefore don’t forgive them.", "bsb": "So mankind is brought low, and man is humbled— do not forgive them!", "asv": "And the mean man is bowed down, and the great man is brought low: therefore forgive them not.", "ylt": "And the low boweth down, and the high is humbled, And Thou acceptest them not.", "dra": "And man hath bowed himself down, and man hath been debased: therefore forgive them not.", "bbe": "And the poor man's head is bent, and the great man goes down on his face: for this cause there will be no forgiveness for their sin.", "geneva": "And a man bowed himselfe, and a man humbled himselfe: therefore spare them not.", "wycliffe": "and a man bowide hymsilf, and a man of ful age was maad low. Therfor foryyue thou not to hem.", "rotherham": "So the mean man boweth down And the great man stoopeth low,—Therefore do not thou forgive them!", "darby": "And the mean man shall be bowed down, and the great man shall be brought low: and do not thou forgive them!", "twenty": "", "jps": "And man boweth down, and man lowereth himself; and Thou canst not bear with them.", "acv": "and so the common man bows down, and the great man degrades himself. Therefore do not forgive them.", "anderson": "", "haweis": "", "noyes": "Therefore shall the mean man be bowed down, And the great man be brought low; And thou wilt not forgive them!", "webster": "And the mean man boweth down, and the great man humbleth himself: therefore forgive them not.", "vulgate": "et incurvavit se homo et humiliatus est vir ne ergo dimittas eis;", "brenton": "And the mean man bowed down, and the great man was humbled: and I will not pardon them."}}, {"v": 10, "ref": "2:10", "o": "בּ֣וֹא בַ/צּ֔וּר וְ/הִטָּמֵ֖ן בֶּֽ/עָפָ֑ר מִ/פְּנֵי֙ פַּ֣חַד יְהוָ֔ה וּ/מֵ/הֲדַ֖ר גְּאֹנֽ/וֹ", "en": {"kjv": "Enter into the rock, and hide thee in the dust, for fear of the Lord, and for the glory of his majesty.", "web": "Enter into the rock, and hide in the dust, from before the terror of Yahweh, and from the glory of his majesty.", "bsb": "Go into the rocks and hide in the dust from the terror of the LORD and the splendor of His majesty.", "asv": "Enter into the rock, and hide thee in the dust, from before the terror of Jehovah, and from the glory of his majesty.", "ylt": "Enter into a rock, and be hidden in dust, Because of the fear of Jehovah, And because of the honour of His excellency.", "dra": "Enter thou into the rock, and hide thee in the pit from the face of the fear of the Lord, and from the glory of his majesty.", "bbe": "Go into a hole in the rock, covering yourselves with dust, in fear of the Lord, before the glory of his power.", "geneva": "Enter into the rocke, and hide thee in the dust from before the feare of the Lord, and from the glory of his maiestie.", "wycliffe": "Entre thou, puple of Juda, in to a stoon, be thou hid in a diche in erthe, fro the face of the drede of the Lord, and fro the glorie of his mageste.", "rotherham": "Enter into the rock, Or hide thee in the dust,—Because of the terribleness of Yahweh, And for his majestic splendour.", "darby": "Enter into the rock, and hide thee in the dust, from before the terror of Jehovah, and from the glory of his majesty.", "twenty": "", "jps": "Enter into the rock, and hide thee in the dust, from before the terror of HaShem, and from the glory of His majesty.", "acv": "Enter into the rock, and hide thee in the dust, from before the terror of Jehovah, and from the glory of his majesty.", "anderson": "", "haweis": "", "noyes": "Go into the rock, hide yourselves in the dust, From the terror of Jehovah, and the glory of his majesty!", "webster": "Enter into the rock, and hide thee in the dust, for fear of the LORD, and for the glory of his majesty.", "vulgate": "ingredere in petram abscondere fossa humo a facie timoris Domini et a gloria maiestatis eius;", "brenton": "Now therefore enter ye into the rocks, and hide yourselves in the earth, for fear of the Lord, and by reason of the glory of his might, when he shall arise to strike terribly the earth."}}, {"v": 11, "ref": "2:11", "o": "עֵינֵ֞י גַּבְה֤וּת אָדָם֙ שָׁפֵ֔ל וְ/שַׁ֖ח ר֣וּם אֲנָשִׁ֑ים וְ/נִשְׂגַּ֧ב יְהוָ֛ה לְ/בַדּ֖/וֹ בַּ/יּ֥וֹם הַ/הֽוּא", "en": {"kjv": "The lofty looks of man shall be humbled, and the haughtiness of men shall be bowed down, and the Lord alone shall be exalted in that day.", "web": "The lofty looks of man will be brought low, the haughtiness of men will be bowed down, and Yahweh alone will be exalted in that day.", "bsb": "The proud look of man will be humbled, and the loftiness of men brought low; the LORD alone will be exalted in that day.", "asv": "The lofty looks of man shall be brought low, and the haughtiness of men shall be bowed down, and Jehovah alone shall be exalted in that day.", "ylt": "The haughty eyes of man have been humbled, And bowed down hath been the loftiness of men, And set on high hath Jehovah alone been in that day.", "dra": "The lofty eyes of man are humbled, and the haughtiness of men shall be made to stoop: and the Lord alone shall be exalted in that day.", "bbe": "The high looks of man will be put to shame, and the pride of men will be made low, and only the Lord will be lifted up in that day.", "geneva": "The hie looke of man shall be humbled, and the loftinesse of men shalbe abased, and the Lord onely shall be exalted in that day.", "wycliffe": "The iyen of an hiy man ben maad low, and the hiynesse of men schal be bowid doun; forsothe the Lord aloone schal be enhaunsid in that dai.", "rotherham": "The lofty looks of mean men, shall be humbled, And, the haughtiness of great men, shall be bowed down,—And Yahweh alone shall be exalted in that day.", "darby": "The lofty eyes of man shall be brought low, and the haughtiness of men shall be bowed down, and Jehovah alone shall be exalted in that day.", "twenty": "", "jps": "The lofty looks of man shall be brought low, and the haughtiness of men shall be bowed down, and HaShem alone shall be exalted in that day.", "acv": "The lofty looks of man shall be brought low, and the haughtiness of men shall be bowed down, and Jehovah alone shall be exalted in that day.", "anderson": "", "haweis": "", "noyes": "The proud looks of man shall be humbled, And the loftiness of mortals shall be brought low; Jehovah alone shall be exalted in that day.", "webster": "The lofty looks of man shall be humbled, and the haughtiness of men shall be abased, and the LORD alone shall be exalted in that day.", "vulgate": "oculi sublimis hominis humiliati sunt et incurvabitur altitudo virorum exaltabitur autem Dominus solus in die illa;", "brenton": "For the eyes of the Lord are high, but man is low; and the haughtiness of men shall be brought low, and the Lord alone shall be exalted in that day."}}, {"v": 12, "ref": "2:12", "o": "כִּ֣י י֞וֹם לַ/יהוָ֧ה צְבָא֛וֹת עַ֥ל כָּל גֵּאֶ֖ה וָ/רָ֑ם וְ/עַ֖ל כָּל נִשָּׂ֥א וְ/שָׁפֵֽל", "en": {"kjv": "For the day of the Lord of hosts shall be upon every one that is proud and lofty, and upon every one that is lifted up; and he shall be brought low:", "web": "For there will be a day of Yahweh of Armies for all that is proud and haughty, and for all that is lifted up; and it shall be brought low:", "bsb": "For the Day of the LORD of Hosts will come against all the proud and lofty, against all that is exalted— it will be humbled—", "asv": "For there shall be a day of Jehovah of hosts upon all that is proud and haughty, and upon all that is lifted up; and it shall be brought low;", "ylt": "For a day is to Jehovah of Hosts, For every proud and high one, And for every lifted up and low one,", "dra": "Because the day of the Lord of hosts shall be upon every one that is proud and highminded, and upon every one that is arrogant, and he shall be humbled.", "bbe": "For the day of the Lord of armies is coming on all the pride of men, and on all who are high and lifted up;", "geneva": "For the day of the Lord of hostes is vpon all the proude and hautie, and vpon all that is exalted: and it shalbe made lowe.", "wycliffe": "For the dai of the Lord of oostis schal be on ech proud man and hiy, and on ech boostere, and he schal be maad low;", "rotherham": "For, a day of Yahweh of hosts, [shall be] —Upon every one who is high and lofty,—And upon every one who is lifted up, And he shall be brought low;", "darby": "For there shall be a day of Jehovah of hosts upon everything proud and lofty, and upon everything lifted up, and it shall be brought low;", "twenty": "", "jps": "For HaShem of hosts hath a day upon all that is proud and lofty, and upon all that is lifted up, and it shall be brought low;", "acv": "For there shall be a day of Jehovah of hosts upon all that is proud and haughty, and upon all that is lifted up, and it shall be brought low,", "anderson": "", "haweis": "", "noyes": "For Jehovah of hosts holdeth a day of judgment Against all that is proud and lofty; Against all that is exalted, and it shall be brought low;", "webster": "For the day of the LORD of hosts [shall be] upon every [one that is] proud and lofty, and upon every [one that is] lifted up; and he shall be brought low:", "vulgate": "quia dies Domini exercituum super omnem superbum et excelsum et super omnem arrogantem et humiliabitur;", "brenton": "For the day of the Lord of hosts shall be upon every one that is proud and haughty, and upon every one that is high and towering, and they shall be brought down;"}}, {"v": 13, "ref": "2:13", "o": "וְ/עַל֙ כָּל אַרְזֵ֣י הַ/לְּבָנ֔וֹן הָ/רָמִ֖ים וְ/הַ/נִּשָּׂאִ֑ים וְ/עַ֖ל כָּל אַלּוֹנֵ֥י הַ/בָּשָֽׁן", "en": {"kjv": "And upon all the cedars of Lebanon, that are high and lifted up, and upon all the oaks of Bashan,", "web": "For all the cedars of Lebanon, that are high and lifted up, for all the oaks of Bashan,", "bsb": "against all the cedars of Lebanon, lofty and lifted up, against all the oaks of Bashan,", "asv": "and upon all the cedars of Lebanon, that are high and lifted up, and upon all the oaks of Bashan,", "ylt": "And for all cedars of Lebanon, The high and the exalted ones, And for all oaks of Bashan,", "dra": "And upon all the tall and lofty cedars of Libanus, and upon all the oaks of Basan.", "bbe": "And on all the high trees of Lebanon, and on all the strong trees of Bashan;", "geneva": "Euen vpon all the cedars of Lebanon, that are hie and exalted, and vpon all the okes of Bashan,", "wycliffe": "and on alle the cedres of the Liban hiye and reisid, and on alle the ookis of Baisan,", "rotherham": "And upon all cedars of Lebanon, that are high and lifted up,—And upon all the oaks of Bashan;", "darby": "and upon all the cedars of Lebanon, high and lifted up, and upon all the oaks of Bashan;", "twenty": "", "jps": "And upon all the cedars of Lebanon that are high and lifted up, and upon all the oaks of Bashan;", "acv": "and upon all the cedars of Lebanon that are high and lifted up, and upon all the oaks of Bashan,", "anderson": "", "haweis": "", "noyes": "Against all the cedars of Lebanon, the high and the exalted, And against all the oaks of Bashan;", "webster": "And upon all the cedars of Lebanon, [that are] high and lifted up, and upon all the oaks of Bashan,", "vulgate": "et super omnes cedros Libani sublimes et erectas et super omnes quercus Basan;", "brenton": "and upon every cedar of Libanus, of them that are high and towering, and upon every oak of Basan,"}}, {"v": 14, "ref": "2:14", "o": "וְ/עַ֖ל כָּל הֶ/הָרִ֣ים הָ/רָמִ֑ים וְ/עַ֖ל כָּל הַ/גְּבָע֥וֹת הַ/נִּשָּׂאֽוֹת", "en": {"kjv": "And upon all the high mountains, and upon all the hills that are lifted up,", "web": "For all the high mountains, for all the hills that are lifted up,", "bsb": "against all the tall mountains, against all the high hills,", "asv": "and upon all the high mountains, and upon all the hills that are lifted up,", "ylt": "And for all the high mountains, And for all the exalted heights,", "dra": "And upon all the high mountains and upon all the elevated hills.", "bbe": "And on all the high mountains, and on all the hills which are lifted up;", "geneva": "And vpon all the hie mountaines, and vpon all the hilles that are lifted vp,", "wycliffe": "and on alle hiy munteyns, and on alle litle hillis, `that ben reisid;", "rotherham": "And upon all the lofty mountains,—And upon all the uplifted hills;", "darby": "and upon all the lofty mountains, and upon all the hills that are lifted up;", "twenty": "", "jps": "And upon all the high mountains, and upon all the hills that are lifted up;", "acv": "and upon all the high mountains, and upon all the hills that are lifted up,", "anderson": "", "haweis": "", "noyes": "Against all the lofty mountains, And against all the high hills;", "webster": "And upon all the high mountains, and upon all the hills [that are] lifted up,", "vulgate": "et super omnes montes excelsos et super omnes colles elevatos;", "brenton": "and upon every high mountain, and upon every high hill,"}}, {"v": 15, "ref": "2:15", "o": "וְ/עַ֖ל כָּל מִגְדָּ֣ל גָּבֹ֑הַ וְ/עַ֖ל כָּל חוֹמָ֥ה בְצוּרָֽה", "en": {"kjv": "And upon every high tower, and upon every fenced wall,", "web": "For every lofty tower, for every fortified wall,", "bsb": "against every high tower, against every fortified wall,", "asv": "and upon every lofty tower, and upon every fortified wall,", "ylt": "And for every high tower, And for every fenced wall,", "dra": "And upon every high tower, and every fenced wall.", "bbe": "And on every high tower, and on every strong wall;", "geneva": "And vpon euery hie tower, and vpon euery strong wall,", "wycliffe": "and on ech hiy tour, and on ech strong wal;", "rotherham": "And upon every high tower,—And upon every fortress wall;", "darby": "and upon every high tower, and upon every fenced wall;", "twenty": "", "jps": "And upon every lofty tower, and upon every fortified wall;", "acv": "and upon every lofty tower, and upon every fortified wall,", "anderson": "", "haweis": "", "noyes": "Against every lofty tower, And against every high wall;", "webster": "And upon every high tower, and upon every fortified wall,", "vulgate": "et super omnem turrem excelsam et super omnem murum munitum;", "brenton": "and upon every high tower, and upon every high wall,"}}, {"v": 16, "ref": "2:16", "o": "וְ/עַ֖ל כָּל אֳנִיּ֣וֹת תַּרְשִׁ֑ישׁ וְ/עַ֖ל כָּל שְׂכִיּ֥וֹת הַ/חֶמְדָּֽה", "en": {"kjv": "And upon all the ships of Tarshish, and upon all pleasant pictures.", "web": "For all the ships of Tarshish, and for all pleasant imagery.", "bsb": "against every ship of Tarshish, and against every stately vessel.", "asv": "and upon all the ships of Tarshish, and upon all pleasant imagery.", "ylt": "And for all ships of Tarshish, And for all desirable pictures.", "dra": "And upon all the ships of Tharsis, and upon all that is fair to behold.", "bbe": "And on all the ships of Tarshish, and on all the fair boats.", "geneva": "And vpon all the shippes of Tarshish, and vpon all pleasant pictures.", "wycliffe": "and on alle schippis of Tharsis, and on al thing which is fair in siyt.", "rotherham": "And upon all the ships of Tarshish,—And upon all desirable banners.", "darby": "and upon all the ships of Tarshish, and upon all pleasant works of art.", "twenty": "", "jps": "And upon all the ships of Tarshish, and upon all delightful imagery.", "acv": "and upon all the ships of Tarshish, and upon all pleasant imagery.", "anderson": "", "haweis": "", "noyes": "Against all the ships of Tarshish, And against all their beautiful flags.", "webster": "And upon all the ships of Tarshish, and upon all pleasant pictures.", "vulgate": "et super omnes naves Tharsis et super omne quod visu pulchrum est;", "brenton": "and upon every ship of the sea, and upon every display of fine ships."}}, {"v": 17, "ref": "2:17", "o": "וְ/שַׁח֙ גַּבְה֣וּת הָ/אָדָ֔ם וְ/שָׁפֵ֖ל ר֣וּם אֲנָשִׁ֑ים וְ/נִשְׂגַּ֧ב יְהוָ֛ה לְ/בַדּ֖/וֹ בַּ/יּ֥וֹם הַ/הֽוּא", "en": {"kjv": "And the loftiness of man shall be bowed down, and the haughtiness of men shall be made low: and the Lord alone shall be exalted in that day.", "web": "The loftiness of man shall be bowed down, and the haughtiness of men shall be brought low; and Yahweh alone shall be exalted in that day.", "bsb": "So the pride of man will be brought low, and the loftiness of men will be humbled; the LORD alone will be exalted in that day,", "asv": "And the loftiness of man shall be bowed down, and the haughtiness of men shall be brought low; and Jehovah alone shall be exalted in that day.", "ylt": "And bowed down hath been the haughtiness of man, And humbled the loftiness of men, And set on high hath Jehovah alone been in that day.", "dra": "And the loftiness of men shall be bowed down, and the haughtiness of men shall be humbled, and the Lord alone shall be exalted in that day.", "bbe": "And the high looks of man will be put to shame, and the pride of men will be made low: and only the Lord will be lifted up in that day.", "geneva": "And the hautinesse of men shalbe brought low, and the loftinesse of men shalbe abased, and the Lord shall onely be exalted in that day.", "wycliffe": "And al the hiynesse of men schal be bowid doun, and the hiynesse of men schal be maad low; and the Lord aloone schal be reisid in that dai,", "rotherham": "And the haughtiness of mean men, shall be humbled,—And the loftiness of great men, shall be laid low,—And Yahweh alone shall be exalted in that day.", "darby": "And the loftiness of man shall be bowed down, and the haughtiness of men shall be brought low; and Jehovah alone shall be exalted in that day:", "twenty": "", "jps": "And the loftiness of man shall be bowed down, and the haughtiness of men shall be brought low; and HaShem alone shall be exalted in that day.", "acv": "And the loftiness of man shall be bowed down, and the haughtiness of men shall be brought low, and Jehovah alone shall be exalted in that day.", "anderson": "", "haweis": "", "noyes": "The pride of man shall be humbled; The loftiness of mortals shall be brought low; Jehovah alone shall be exalted in that day.", "webster": "And the loftiness of man shall be abased, and the haughtiness of men shall be made low: and the LORD alone shall be exalted in that day.", "vulgate": "et incurvabitur sublimitas hominum et humiliabitur altitudo virorum et elevabitur Dominus solus in die illa;", "brenton": "And every man shall be brought low, and the pride of men shall fall: and the Lord alone shall be exalted in that day."}}, {"v": 18, "ref": "2:18", "o": "וְ/הָ/אֱלִילִ֖ים כָּלִ֥יל יַחֲלֹֽף", "en": {"kjv": "And the idols he shall utterly abolish.", "web": "The idols shall utterly pass away.", "bsb": "and the idols will vanish completely.", "asv": "And the idols shall utterly pass away.", "ylt": "And the idols--they completely pass away.", "dra": "And idols shall be utterly destroyed.", "bbe": "And the images will never be seen again.", "geneva": "And the idoles will he vtterly destroy.", "wycliffe": "and idols schulen be brokun togidere outirli.", "rotherham": "And, the idols, shall wholly pass away;", "darby": "and the idols shall utterly pass away.", "twenty": "", "jps": "And the idols shall utterly pass away.", "acv": "And the idols shall utterly pass away.", "anderson": "", "haweis": "", "noyes": "The idols shall wholly pass away;", "webster": "And the idols he will utterly abolish.", "vulgate": "et idola penitus conterentur;", "brenton": "And they shall hide all idols made with hands,"}}, {"v": 19, "ref": "2:19", "o": "וּ/בָ֨אוּ֙ בִּ/מְעָר֣וֹת צֻרִ֔ים וּ/בִ/מְחִלּ֖וֹת עָפָ֑ר מִ/פְּנֵ֞י פַּ֤חַד יְהוָה֙ וּ/מֵ/הֲדַ֣ר גְּאוֹנ֔/וֹ בְּ/קוּמ֖/וֹ לַ/עֲרֹ֥ץ הָ/אָֽרֶץ", "en": {"kjv": "And they shall go into the holes of the rocks, and into the caves of the earth, for fear of the Lord, and for the glory of his majesty, when he ariseth to shake terribly the earth.", "web": "Men shall go into the caves of the rocks, and into the holes of the earth, from before the terror of Yahweh, and from the glory of his majesty, when he arises to shake the earth mightily.", "bsb": "Men will flee to caves in the rocks and holes in the ground, away from the terror of the LORD and from the splendor of His majesty, when He rises to shake the earth.", "asv": "And men shall go into the caves of the rocks, and into the holes of the earth, from before the terror of Jehovah, and from the glory of his majesty, when he ariseth to shake mightily the earth.", "ylt": "And men have entered into caverns of rocks, And into caves of dust, Because of the fear of Jehovah, And because of the honour of His excellency, In His rising to terrify the earth.", "dra": "And they shall go into the holes of rocks, and into the caves of the earth from the face of the fear of the Lord, and from the glory of his majesty, when he shall rise up to strike the earth.", "bbe": "And men will go into cracks of the rocks, and into holes of the earth, for fear of the Lord, and before the glory of his power, when he comes out of his place, shaking the earth with his strength.", "geneva": "Then they shall goe into the holes of the rockes, and into the caues of the earth, from before the feare of the Lord, and from the glory of his maiestie, when he shall arise to destroy the earth.", "wycliffe": "And thei schulen entre in to dennes of stoonys, and in to the swolewis of erthe, fro the face of the inward drede of the Lord, and fro the glorie of his maieste, whanne he schal ryse to smyte the lond.", "rotherham": "And they shall enter into the holes of the rocks, and into the caves of clay,—Because of the terribleness of Yahweh, And for his majestic splendour, When he ariseth to shake terribly the earth.", "darby": "And they shall go into the caves of the rocks, and into the holes of the earth, from before the terror of Jehovah, and from the glory of his majesty, when he shall arise to terrify the earth.", "twenty": "", "jps": "And men shall go into the caves of the rocks, and into the holes of the earth, from before the terror of HaShem, and from the glory of His majesty, when He ariseth to shake mightily the earth.", "acv": "And men shall go into the caves of the rocks, and into the holes of the earth, from before the terror of Jehovah, and from the glory of his majesty, when he arises to shake the earth mightily.", "anderson": "", "haweis": "", "noyes": "And men shall go into clefts of the rocks, and caves of the earth, From the terror of Jehovah, and the glory of his majesty, When he ariseth to make the earth tremble.", "webster": "And they shall go into the holes of the rocks, and into the caves of the earth, for fear of the LORD, and for the glory of his majesty, when he ariseth to shake terribly the earth.", "vulgate": "et introibunt in speluncas petrarum et in voragines terrae a facie formidinis Domini et a gloria maiestatis eius cum surrexerit percutere terram;", "brenton": "having carried them into the caves, and into the clefts of the rocks, and into the caverns of the earth, for fear of the Lord, and by reason of the glory of his might, when he shall arise to strike terribly the earth."}}, {"v": 20, "ref": "2:20", "o": "בַּ/יּ֤וֹם הַ/הוּא֙ יַשְׁלִ֣יךְ הָ/אָדָ֔ם אֵ֚ת אֱלִילֵ֣י כַסְפּ֔/וֹ וְ/אֵ֖ת אֱלִילֵ֣י זְהָב֑/וֹ אֲשֶׁ֤ר עָֽשׂוּ ל/וֹ֙ לְ/הִֽשְׁתַּחֲוֺ֔ת לַ/חְפֹּ֥ר פֵּר֖וֹת וְ/לָ/עֲטַלֵּפִֽים", "en": {"kjv": "In that day a man shall cast his idols of silver, and his idols of gold, which they made each one for himself to worship, to the moles and to the bats;", "web": "In that day, men shall cast away their idols of silver, and their idols of gold, which have been made for themselves to worship, to the moles and to the bats;", "bsb": "In that day men will cast away to the moles and bats their idols of silver and gold— the idols they made to worship.", "asv": "In that day men shall cast away their idols of silver, and their idols of gold, which have been made for them to worship, to the moles and to the bats;", "ylt": "In that day doth man cast his idols of silver, And his idols of gold, That they have made for him to worship, To moles, and to bats,", "dra": "In that day a man shall cast away his idols of silver, and his idols of gold, which he had made for himself to adore, moles and bats.", "bbe": "In that day men will put their images of silver and of gold, which they made for worship, in the keeping of the beasts of the dark places;", "geneva": "At that day shall man cast away his siluer idoles, and his golden idoles (which they had made themselues to worship them) to the mowles and to the backes,", "wycliffe": "In that dai a man schal caste awei the idols of his siluer, and the symylacris of his gold, whiche he hadde maad to hym silf, for to worschipe moldewarpis and backis, `ether rere myis.", "rotherham": "In that day shall the son of earth cast his idols of silver, and his idols of gold,—which had been made for him to worship, into the hole of the mice, and to the bats;", "darby": "In that day men shall cast away their idols of silver and their idols of gold, which they made [each] for himself to worship, to the moles and to the bats;", "twenty": "", "jps": "In that day a man shall cast away his idols of silver, and his idols of gold, which they made for themselves to worship, to the moles and to the bats;", "acv": "In that day men shall cast away their idols of silver, and their idols of gold, which have been made for them to worship, to the moles and to the bats,", "anderson": "", "haweis": "", "noyes": "At that time shall men cast away their idols of silver and their idols of gold, Which they have made to worship, To the moles and the bats;", "webster": "In that day a man shall cast his idols of silver, and his idols of gold, which they made [each one] for himself to worship, to the moles and to the bats;", "vulgate": "in die illa proiciet homo idola argenti sui et simulacra auri sui quae fecerat sibi ut adoraret talpas et vespertiliones;", "brenton": "For in that day a man shall cast forth his silver and gold abominations, which they made in order to worship vanities and bats;"}}, {"v": 21, "ref": "2:21", "o": "לָ/בוֹא֙ בְּ/נִקְר֣וֹת הַ/צֻּרִ֔ים וּ/בִ/סְעִפֵ֖י הַ/סְּלָעִ֑ים מִ/פְּנֵ֞י פַּ֤חַד יְהוָה֙ וּ/מֵ/הֲדַ֣ר גְּאוֹנ֔/וֹ בְּ/קוּמ֖/וֹ לַ/עֲרֹ֥ץ הָ/אָֽרֶץ", "en": {"kjv": "To go into the clefts of the rocks, and into the tops of the ragged rocks, for fear of the Lord, and for the glory of his majesty, when he ariseth to shake terribly the earth.", "web": "To go into the caverns of the rocks, and into the clefts of the ragged rocks, from before the terror of Yahweh, and from the glory of his majesty, when he arises to shake the earth mightily.", "bsb": "They will flee to caverns in the rocks and crevices in the cliffs, away from the terror of the LORD and from the splendor of His majesty, when He rises to shake the earth.", "asv": "to go into the caverns of the rocks, and into the clefts of the ragged rocks, from before the terror of Jehovah, and from the glory of his majesty, when he ariseth to shake mightily the earth.", "ylt": "To enter into cavities of the rocks, And into clefts of the high places, Because of the fear of Jehovah, And because of the honour of His excellency, In His rising to terrify the earth.", "dra": "And he shall go into the clefts of rocks, and into the holes of stones from the face of the fear of the Lord, and from the glory of his majesty, when he shall rise up to strike the earth.", "bbe": "To take cover in the cracks of the rocks, and in the holes of the hills, for fear of the Lord, and before the glory of his power, when he comes out of his place, shaking the earth with his strength.", "geneva": "To goe into the holes of the rockes, and into the toppes of the ragged rockes from before the feare of the Lord, and from the glory of his maiestie, when he shall rise to destroy the earth.", "wycliffe": "And he schal entre in to chynnis, ethir crasyngis, of stoonys, and in to the caues of hard roochis, fro the face of the inward drede of the Lord, and fro the glorie of his mageste, whanne he schal ryse to smyte the lond.", "rotherham": "That he may enter into the clefts of the rocks, and into the fissures of the crags,—Because of the terribleness of Yahweh, And for his majestic splendour, When he ariseth to shake terribly the earth.", "darby": "to go into the clefts of the rocks, and into the fissures of the cliffs, from before the terror of Jehovah, and from the glory of his majesty, when he shall arise to terrify the earth.", "twenty": "", "jps": "To go into the clefts of the rocks, and into the crevices of the crags, from before the terror of HaShem, and from the glory of His majesty, when he ariseth to shake mightily the earth.", "acv": "to go into the caverns of the rocks, and into the clefts of the ragged rocks, from before the terror of Jehovah, and from the glory of his majesty, when he arises to shake the earth mightily.", "anderson": "", "haweis": "", "noyes": "Fleeing into caves of the rocks, and clefts of the craggy rocks, From the terror of Jehovah, and the glory of his majesty, When he ariseth to make the earth tremble.", "webster": "To go into the clefts of the rocks, and into the tops of the ragged rocks, for fear of the LORD, and for the glory of his majesty, when he ariseth to shake terribly the earth.", "vulgate": "et ingredietur fissuras petrarum et cavernas saxorum a facie formidinis Domini et a gloria maiestatis eius cum surrexerit percutere terram;", "brenton": "to enter into the caverns of the solid rock, and into the clefts of the rocks, for fear of the Lord, and by reason of the glory of his might, when he shall arise to strike terribly the earth."}}, {"v": 22, "ref": "2:22", "o": "חִדְל֤וּ לָ/כֶם֙ מִן הָ֣/אָדָ֔ם אֲשֶׁ֥ר נְשָׁמָ֖ה בְּ/אַפּ֑/וֹ כִּֽי בַ/מֶּ֥ה נֶחְשָׁ֖ב הֽוּא", "en": {"kjv": "Cease ye from man, whose breath is in his nostrils: for wherein is he to be accounted of?", "web": "Stop trusting in man, whose breath is in his nostrils; for of what account is he?", "bsb": "Put no more trust in man, who has only the breath in his nostrils. Of what account is he?", "asv": "Cease ye from man, whose breath is in his nostrils; for wherein is he to be accounted of?", "ylt": "Cease for you from man, Whose breath is in his nostrils, For--in what is he esteemed?", "dra": "Cease ye therefore from the man, whose breath is in his nostrils, for he is reputed high.", "bbe": "Have no more to do with man, whose life is only a breath, for he is of no value.", "geneva": "Cease you from the man whose breath is in his nostrels: for wherein is he to be esteemed?", "wycliffe": "Therfor ceesse ye fro a man, whos spirit is in hise nose thirlis, for he is arettid hiy.", "rotherham": "Cease ye from the son of earth, In whose nostrils is but a breath,—For wherein to be reckoned upon, is he?", "darby": "Cease ye from man, whose breath is in his nostrils; for what account is to be made of him?", "twenty": "", "jps": "Cease ye from man, in whose nostrils is a breath; for how little is he to be accounted!", "acv": "Cease ye from man, whose breath is in his nostrils, for how is he to be accounted of?", "anderson": "", "haweis": "", "noyes": "Trust, then, no more in man, Whose breath is in his nostrils! For what account is to be made of him!", "webster": "Cease ye from man, whose breath [is] in his nostrils: for wherein is he to be accounted of?", "vulgate": "quiescite ergo ab homine cuius spiritus in naribus eius quia excelsus reputatus est ipse;", "brenton": ""}}]}, {"c": 3, "verses": [{"v": 1, "ref": "3:1", "o": "כִּי֩ הִנֵּ֨ה הָ/אָד֜וֹן יְהוָ֣ה צְבָא֗וֹת מֵסִ֤יר מִ/ירוּשָׁלִַ֨ם֙ וּ/מִ֣/יהוּדָ֔ה מַשְׁעֵ֖ן וּ/מַשְׁעֵנָ֑ה כֹּ֚ל מִשְׁעַן לֶ֔חֶם וְ/כֹ֖ל מִשְׁעַן מָֽיִם", "en": {"kjv": "For, behold, the Lord, the Lord of hosts, doth take away from Jerusalem and from Judah the stay and the staff, the whole stay of bread, and the whole stay of water,", "web": "For, behold, the Lord, Yahweh of Armies, takes away from Jerusalem and from Judah supply and support, the whole supply of bread, and the whole supply of water;", "bsb": "For behold, the Lord GOD of Hosts is about to remove from Jerusalem and Judah both supply and support: the whole supply of food and water,", "asv": "For, behold, the Lord, Jehovah of hosts, doth take away from Jerusalem and from Judah stay and staff, the whole stay of bread, and the whole stay of water;", "ylt": "For, lo, the Lord, Jehovah of Hosts, Is turning aside from Jerusalem, And from Judah, stay and staff, Every stay of bread, and every stay of water.", "dra": "For behold the sovereign Lord of hosts shall take away from Jerusalem, and from Juda the valiant and the strong, the whole strength of bread, and the whole strength of water.", "bbe": "For the Lord, the Lord of armies, is about to take away from Jerusalem and from Judah all their support; their store of bread and of water;", "geneva": "For lo, the Lord God of hostes will take away from Ierusalem and from Iudah the stay and the strength: euen all the staye of bread, and all the stay of water,", "wycliffe": "For lo! the lordli gouernour, the Lord of oostis, schal take awei fro Jerusalem and fro Juda a myyti man, and strong, and al the strengthe of breed, and al the strengthe of watir;", "rotherham": "For lo! the Lord, Yahweh of hosts, removing from Jerusalem and from Judah, The stay and staff,—The whole stay of bread, And the whole stay of water:", "darby": "For behold, the Lord, Jehovah of hosts, will take away from Jerusalem and from Judah stay and staff, the whole stay of bread, and the whole stay of water,", "twenty": "", "jps": "For, behold, the L-rd, HaShem of hosts, doth take away from Jerusalem and from Judah stay and staff, every stay of bread, and every stay of water;", "acv": "For, behold, the Lord, Jehovah of hosts, takes away from Jerusalem and from Judah support and staff, the whole support of bread, and the whole support of water,", "anderson": "", "haweis": "", "noyes": "For behold, the Lord, Jehovah of hosts, Taketh away from Jerusalem and from Judah every stay and support; The whole stay of bread, and the whole stay of water;", "webster": "For behold, the Lord, the LORD of hosts, doth take away from Jerusalem and from Judah the rod and the staff, the whole support of bread, and the whole support of water,", "vulgate": "ecce enim Dominator Deus exercituum auferet ab Hierusalem et ab Iuda validum et fortem omne robur panis et omne robur aquae;", "brenton": "Behold now, the Lord, the Lord of hosts, will take away from Jerusalem and from Judea the mighty man and mighty woman, the strength of bread, and the strength of water,"}}, {"v": 2, "ref": "3:2", "o": "גִּבּ֖וֹר וְ/אִ֣ישׁ מִלְחָמָ֑ה שׁוֹפֵ֥ט וְ/נָבִ֖יא וְ/קֹסֵ֥ם וְ/זָקֵֽן", "en": {"kjv": "The mighty man, and the man of war, the judge, and the prophet, and the prudent, and the ancient,", "web": "the mighty man, the man of war, the judge, the prophet, the diviner, the elder,", "bsb": "the mighty man and the warrior, the judge and the prophet, the soothsayer and the elder,", "asv": "the mighty man, and the man of war; the judge, and the prophet, and the diviner, and the elder;", "ylt": "Hero and man of war, judge and prophet, And diviner and elder,", "dra": "The strong man, and the man of war, the judge, and the prophet and the cunning man, and the ancient.", "bbe": "The strong man and the man of war; the judge and the prophet; the man who has knowledge of secret arts, and the man who is wise because of his years;", "geneva": "The strong man, and the man of warre, the iudge and the prophet, the prudent and the aged,", "wycliffe": "a strong man, and a man a werriour, and a domesman, and a profete, and a false dyuynour in auteris, and an elde man,", "rotherham": "Man of might and man of war,—Judge and prophet And diviner and elder;", "darby": "the mighty man and the man of war, the judge and the prophet, and the diviner and the elder,", "twenty": "", "jps": "The mighty man, and the man of war; the judge, and the prophet, and the diviner, and the elder;", "acv": "the mighty man, and the man of war, the judge, and the prophet, and the diviner, and the elder,", "anderson": "", "haweis": "", "noyes": "The mighty man, and the warrior, The judge, the prophet, the diviner, and the sage,", "webster": "The mighty man, and the man of war, the judge, and the prophet, and the prudent, and the ancient,", "vulgate": "fortem et virum bellatorem iudicem et prophetam et ariolum et senem;", "brenton": "the great and mighty man, the warrior and the judge, and the prophet, and the counsellor, and the elder,"}}, {"v": 3, "ref": "3:3", "o": "שַׂר חֲמִשִּׁ֖ים וּ/נְשׂ֣וּא פָנִ֑ים וְ/יוֹעֵ֛ץ וַ/חֲכַ֥ם חֲרָשִׁ֖ים וּ/נְב֥וֹן לָֽחַשׁ", "en": {"kjv": "The captain of fifty, and the honourable man, and the counsellor, and the cunning artificer, and the eloquent orator.", "web": "the captain of fifty, the honorable man, the counselor, the skilled craftsman, and the clever enchanter.", "bsb": "the commander of fifty and the dignitary, the counselor, the cunning magician, and the clever enchanter.", "asv": "the captain of fifty, and the honorable man, and the counsellor, and the expert artificer, and the skilful enchanter.", "ylt": "Head of fifty, and accepted of faces, And counsellor, and the wise of artificers, And the intelligent of charmers.", "dra": "The captain over fifty, and the honourable in countenance, and the counsellor, and the architect, and the skilful in eloquent speech.", "bbe": "The captain of fifty, and the man of high position, and the wise guide, and the wonder-worker, and he who makes use of secret powers.", "geneva": "The captaine of fiftie, and the honourable, and the counseller, and the cunning artificer, and the eloquent man.", "wycliffe": "a prince ouer fifti men, and a worschipful man in cheer, and a counselour, and a wijs man of principal crafti men, and a prudent man of mystik, ethir goostli, speche.", "rotherham": "Captain of fifty, and favourite; And counsellor and skilled artificer, And master of magical formulas;", "darby": "the captain of fifty, and the honourable man, and the counsellor, and the clever among artificers, and the one versed in enchantments.", "twenty": "", "jps": "The captain of fifty, and the man of rank, and the counsellor, and the cunning charmer, and the skilful enchanter.", "acv": "the captain of fifty, and the honorable man, and the counselor, and the expert craftsman, and the skilful enchanter.", "anderson": "", "haweis": "", "noyes": "The captain of fifty, and the honorable man, The counsellor, the expert in arts, and the skilful in charms.", "webster": "The captain of fifty, and the honorable man, and the counselor, and the skillful artificer, and the eloquent orator.", "vulgate": "principem super quinquaginta et honorabilem vultu et consiliarium sapientem de architectis et prudentem eloquii mystici;", "brenton": "the captain of fifty also, and the honourable counsellor, and the wise artificer, and the intelligent hearer."}}, {"v": 4, "ref": "3:4", "o": "וְ/נָתַתִּ֥י נְעָרִ֖ים שָׂרֵי/הֶ֑ם וְ/תַעֲלוּלִ֖ים יִמְשְׁלוּ בָֽ/ם", "en": {"kjv": "And I will give children to be their princes, and babes shall rule over them.", "web": "I will give boys to be their princes, and children shall rule over them.", "bsb": "“I will make mere lads their leaders, and children will rule over them.”", "asv": "And I will give children to be their princes, and babes shall rule over them.", "ylt": "And I have made youths their heads, And sucklings rule over them.", "dra": "And I will give children to be their princes, and the effeminate shall rule over them.", "bbe": "And I will make children their chiefs, and foolish ones will have rule over them.", "geneva": "And I will appoint children to bee their princes, and babes shall rule ouer them.", "wycliffe": "And Y schal yyue children the princes of hem, and men of wymmens condiciouns schulen be lordis of hem.", "rotherham": "And I will appoint boys to be their princes,—And, petulant children, shall rule over them,", "darby": "And I will appoint youths as their princes, and children shall rule over them.", "twenty": "", "jps": "And I will give children to be their princes, and babes shall rule over them.", "acv": "And I will give sons to be their rulers, and babes shall rule over them.", "anderson": "", "haweis": "", "noyes": "And I will make boys their princes, And children shall rule over them.", "webster": "And I will give children [to be] their princes, and babes shall rule over them.", "vulgate": "et dabo pueros principes eorum et effeminati dominabuntur eis;", "brenton": "And I will make youths their princes, and mockers shall have dominion over them."}}, {"v": 5, "ref": "3:5", "o": "וְ/נִגַּ֣שׂ הָ/עָ֔ם אִ֥ישׁ בְּ/אִ֖ישׁ וְ/אִ֣ישׁ בְּ/רֵעֵ֑/הוּ יִרְהֲב֗וּ הַ/נַּ֨עַר֙ בַּ/זָּקֵ֔ן וְ/הַ/נִּקְלֶ֖ה בַּ/נִּכְבָּֽד", "en": {"kjv": "And the people shall be oppressed, every one by another, and every one by his neighbour: the child shall behave himself proudly against the ancient, and the base against the honourable.", "web": "The people will be oppressed, everyone by another, and everyone by his neighbor. The child will behave himself proudly against the old man, and the base against the honorable.", "bsb": "The people will oppress one another, man against man, neighbor against neighbor; the young will rise up against the old, and the base against the honorable.", "asv": "And the people shall be oppressed, every one by another, and every one by his neighbor: the child shall behave himself proudly against the old man, and the base against the honorable.", "ylt": "And the people hath exacted--man upon man, Even a man on his neighbour, Enlarge themselves do the youths against the aged, And the lightly esteemed against the honoured.", "dra": "And the people shall rush one upon another, and every man against his neighbour: the child shall make a tumult against the ancient, and the base against the honourable.", "bbe": "And the people will be crushed, every one by his neighbour; the young will be full of pride against the old, and those of low position will be lifted up against the noble.", "geneva": "The people shalbe oppressed one of another, and euery one by his neighbour: the children shall presume against the ancient, and the vile against the honourable.", "wycliffe": "And the puple schal falle doun, a man to a man, ech man to his neiybore; a child schal make noyse ayens an eld man, and an vnnoble man ayens a noble man.", "rotherham": "And the people will, tyrannise, Every man over his fellow-man, And every man over his friend,—And they will rage The boy against, the elder, And the despised, against, the honourable,", "darby": "And the people shall be oppressed one by the other, and each by his neighbour; the child will be insolent against the elder, and the base against the honourable.", "twenty": "", "jps": "And the people shall oppress one another, every man his fellow, and every man his neighbour; the child shall behave insolently against the aged, and the base against the honourable,", "acv": "And the people shall be oppressed, every one by another, and every one by his neighbor. The child shall behave himself proudly against the old man, and the base against the honorable.", "anderson": "", "haweis": "", "noyes": "And the people shall oppress one another, Man striving against man, and neighbor against neighbor; The boy shall behave himself insolently toward the aged, And the base toward the honorable.", "webster": "And the people shall be oppressed, every one by another, and every one by his neighbor: the child shall behave himself proudly against the elder, and the base against the honorable.", "vulgate": "et inruet populus vir ad virum unusquisque ad proximum suum tumultuabitur puer contra senem et ignobilis contra nobilem;", "brenton": "And the people shall fall, man upon man, and every man upon his neighbor: the child shall insult the elder man, and the base the honourable."}}, {"v": 6, "ref": "3:6", "o": "כִּֽי יִתְפֹּ֨שׂ אִ֤ישׁ בְּ/אָחִי/ו֙ בֵּ֣ית אָבִ֔י/ו שִׂמְלָ֣ה לְ/כָ֔ה קָצִ֖ין תִּֽהְיֶה לָּ֑/נוּ וְ/הַ/מַּכְשֵׁלָ֥ה הַ/זֹּ֖את תַּ֥חַת יָדֶֽ/ךָ", "en": {"kjv": "When a man shall take hold of his brother of the house of his father, saying, Thou hast clothing, be thou our ruler, and let this ruin be under thy hand:", "web": "Indeed a man shall take hold of his brother in the house of his father, saying, “You have clothing, you be our ruler, and let this ruin be under your hand.”", "bsb": "A man will seize his brother within his father’s house: “You have a cloak—you be our leader! Take charge of this heap of rubble.”", "asv": "When a man shall take hold of his brother in the house of his father, saying, Thou hast clothing, be thou our ruler, and let this ruin be under thy hand;", "ylt": "When one layeth hold on his brother, Of the house of his father, by the garment, `Come, a ruler thou art to us, And this ruin is under thy hand.'", "dra": "For a man shall take hold of his brother, one of the house of his father, saying: Thou hast a garment, be thou our ruler, and let this ruin be under thy hand.", "bbe": "When one man puts his hand on another in his father's house, and says, You have clothing, be our ruler and be responsible for us in our sad condition:", "geneva": "When euery one shall take holde of his brother of the house of his father, and say, Thou hast clothing: thou shalt bee our prince, and let this fall be vnder thine hand.", "wycliffe": "For a man schal take his brother, the meneal of his fadir, and schal seie, A clooth is to thee, be thou oure prince; forsothe this fallyng be vndur thin hond.", "rotherham": "When a man shall lay hold, on his brother of the house of his father, [saying] —Clothing, hast thou, Become thou our, ruler, This downfall, be under thy hand,", "darby": "When a man shall take hold of his brother, in his father's house, [and shall say:] Thou hast clothing; be our chief, and let this ruin be under thy hand;", "twenty": "", "jps": "For a man shall take hold of his brother of the house of his father: 'Thou hast a mantle, be thou our ruler, and let this ruin be under thy hand.'", "acv": "When a man shall take hold of his brother in the house of his father, saying, Thou have clothing, be thou our ruler, and let this ruin be under thy hand,", "anderson": "", "haweis": "", "noyes": "Then shall a man take hold of his brother in his father’s house, [and say,] Thou hast yet clothing, Be thou our ruler, And take this ruin into thy hands!", "webster": "When a man shall take hold of his brother of the house of his father, [saying], Thou hast clothing, be thou our ruler, and [let] this ruin [be] under thy hand:", "vulgate": "adprehendet enim vir fratrem suum domesticum patris sui vestimentum tibi est princeps esto noster ruina autem haec sub manu tua;", "brenton": "For a man shall lay hold of his brother, as one of his father's household, saying, Thou hast raiment, be thou our ruler, and let my meat be under thee."}}, {"v": 7, "ref": "3:7", "o": "יִשָּׂא֩ בַ/יּ֨וֹם הַ/ה֤וּא לֵ/אמֹר֙ לֹא אֶהְיֶ֣ה חֹבֵ֔שׁ וּ/בְ/בֵיתִ֕/י אֵ֥ין לֶ֖חֶם וְ/אֵ֣ין שִׂמְלָ֑ה לֹ֥א תְשִׂימֻ֖/נִי קְצִ֥ין עָֽם", "en": {"kjv": "In that day shall he swear, saying, I will not be an healer; for in my house is neither bread nor clothing: make me not a ruler of the people.", "web": "In that day he will cry out, saying, “I will not be a healer; for in my house is neither bread nor clothing. You shall not make me ruler of the people.”", "bsb": "On that day he will cry aloud: “I am not a healer. I have no food or clothing in my house. Do not make me leader of the people!”", "asv": "in that day shall he lift up his voice, saying, I will not be a healer; for in my house is neither bread nor clothing: ye shall not make me ruler of the people.", "ylt": "He lifteth up, in that day, saying: `I am not a binder up, And in my house is neither bread nor garment, Ye do not make me a ruler of the people.'", "dra": "In that day he shall answer, saying: I am no healer, and in my house there is no bread, nor clothing: make me not ruler of the people.", "bbe": "Then he will say with an oath, I will not be a helper, for in my house there is no bread or clothing: I will not let you make me a ruler of the people.", "geneva": "In that day hee shall sweare, saying, I cannot bee an helper: for there is no bread in mine house, nor clothing: therefore make me no prince of the people.", "wycliffe": "And he schal answere in that dai, and seie, Y am no leche, and nether breed, nether cloth is in myn hous; nyle ye make me prince of the puple.", "rotherham": "He will swear, in that day, saying—I will take no control, When in mine own house, is neither food nor clothing,—Ye must not set me for a ruler of people!", "darby": "he will lift up [his hand] in that day, saying, I cannot be a healer, and in my house there is neither bread nor clothing; ye shall not make me a chief of the people.", "twenty": "", "jps": "In that day shall he swear, saying: 'I will not be a healer; for in my house is neither bread nor a mantle; ye shall not make me ruler of a people.'", "acv": "in that day he shall lift up his voice, saying, I will not be a healer, for in my house is neither bread nor clothing. Ye shall not make me ruler of the people.", "anderson": "", "haweis": "", "noyes": "But in that day shall he lift up his hand, and say: I am no healer; In my house is neither bread nor raiment; Make not me ruler of the people!", "webster": "In that day shall he swear, saying, I will not be a healer; for in my house [is] neither bread nor clothing: make me not a ruler of the people.", "vulgate": "respondebit in die illa dicens non sum medicus et in domo mea non est panis neque vestimentum nolite constituere me principem populi;", "brenton": "And he shall answer in that day, and say, I will not be thy ruler; for I have no bread in my house, nor raiment: I will not be the ruler of this people."}}, {"v": 8, "ref": "3:8", "o": "כִּ֤י כָשְׁלָה֙ יְר֣וּשָׁלִַ֔ם וִ/יהוּדָ֖ה נָפָ֑ל כִּֽי לְשׁוֹנָ֤/ם וּ/מַֽעַלְלֵי/הֶם֙ אֶל יְהוָ֔ה לַ/מְר֖וֹת עֵנֵ֥י כְבוֹדֽ/וֹ", "en": {"kjv": "For Jerusalem is ruined, and Judah is fallen: because their tongue and their doings are against the Lord, to provoke the eyes of his glory.", "web": "For Jerusalem is ruined, and Judah is fallen; because their tongue and their doings are against Yahweh, to provoke the eyes of his glory.", "bsb": "For Jerusalem has stumbled and Judah has fallen because they spoke and acted against the LORD, defying His glorious presence.", "asv": "For Jerusalem is ruined, and Judah is fallen; because their tongue and their doings are against Jehovah, to provoke the eyes of his glory.", "ylt": "For stumbled hath Jerusalem, and Judah hath fallen, For their tongue and their doings are against Jehovah, To provoke the eyes of His glory.", "dra": "For Jerusalem is ruined, and Juda is fallen: because their tongue, and their devices are against the Lord, to provoke the eyes of his majesty.", "bbe": "For Jerusalem has become feeble, and destruction has come on Judah, because their words and their acts are against the Lord, moving the eyes of his glory to wrath.", "geneva": "Doubtlesse Ierusalem is fallen, and Iudah is fallen downe, because their tongue and workes are against the Lord, to prouoke the eyes of his glory.", "wycliffe": "For whi Jerusalem felle doun, and Juda felle doun togidere; for the tunge of hem, and the fyndingis of hem weren ayens the Lord, for to terre to wraththe the iyen of his mageste.", "rotherham": "For stumbled hath Jerusalem, and, Judah, hath fallen,—Because, their tongue and their doings, are against Yahweh, Provoking his glorious presence,", "darby": "For Jerusalem stumbleth and Judah falleth, because their tongue and their doings are against Jehovah, to provoke the eyes of his glory.", "twenty": "", "jps": "For Jerusalem is ruined, and Judah is fallen; because their tongue and their doings are against HaShem, to provoke the eyes of His glory.", "acv": "For Jerusalem is ruined, and Judah is fallen, because their tongue and their doings are against Jehovah, to provoke the eyes of his glory.", "anderson": "", "haweis": "", "noyes": "For Jerusalem tottereth, and Judah falleth, Because their tongues and their deeds are against Jehovah, To provoke his holy eyes.", "webster": "For Jerusalem is ruined, and Judah is fallen: because their tongue and their doings [are] against the LORD, to provoke the eyes of his glory.", "vulgate": "ruit enim Hierusalem et Iudas concidit quia lingua eorum et adinventiones eorum contra Dominum ut provocarent oculos maiestatis eius;", "brenton": "For Jerusalem is ruined, and Judea has fallen, and their tongues have spoken with iniquity, disobedient as they are towards the Lord."}}, {"v": 9, "ref": "3:9", "o": "הַכָּרַ֤ת פְּנֵי/הֶם֙ עָ֣נְתָה בָּ֔/ם וְ/חַטָּאתָ֛/ם כִּ/סְדֹ֥ם הִגִּ֖ידוּ לֹ֣א כִחֵ֑דוּ א֣וֹי לְ/נַפְשָׁ֔/ם כִּֽי גָמְל֥וּ לָ/הֶ֖ם רָעָֽה", "en": {"kjv": "The shew of their countenance doth witness against them; and they declare their sin as Sodom, they hide it not. Woe unto their soul! for they have rewarded evil unto themselves.", "web": "The look of their faces testify against them. They parade their sin like Sodom. They don’t hide it. Woe to their soul! For they have brought disaster upon themselves.", "bsb": "The expression on their faces testifies against them, and like Sodom they flaunt their sin; they do not conceal it. Woe to them, for they have brought disaster upon themselves.", "asv": "The show of their countenance doth witness against them; and they declare their sin as Sodom, they hide it not. Woe unto their soul! for they have done evil unto themselves.", "ylt": "The appearance of their faces witnessed against them, And their sin, as Sodom, they declared, They have not hidden! Woe to their soul, For they have done to themselves evil.", "dra": "The shew of their countenance hath answered them: and they have proclaimed abroad their sin as Sodom, and they have not hid it: woe to their souls, for evils are rendered to them.", "bbe": "Their respect for a man's position is a witness against them; and their sin is open to the view of all; like that of Sodom, it is not covered. A curse on their soul! for the measure of their sin is full.", "geneva": "The triall of their countenance testifieth against them, yea, they declare their sinnes as Sodom, they hide them not. Wo be vnto their soules: for they haue rewarded euil vnto themselues.", "wycliffe": "The knowyng of her cheer schal answere to hem; and thei prechiden her synne, as Sodom dide, and hidden not. Wo to the soule of hem, for whi yuels ben yoldun to hem.", "rotherham": "The show of their face, hath answered against them, And their sin—like Sodom, have they told, they have not concealed it. Alas for their souls! For they have requited to themselves, calamity.", "darby": "The look of their face doth witness against them, and they declare their sin as Sodom: they hide it not. Woe unto their soul! for they have brought evil upon themselves.", "twenty": "", "jps": "The show of their countenance doth witness against them; and they declare their sin as Sodom, they hide it not. Woe unto their soul! for they have wrought evil unto themselves.", "acv": "The show of their countenance witnesses against them, and they declare their sin as Sodom; they do not hide it. Woe to their soul! For they have done evil to themselves.", "anderson": "", "haweis": "", "noyes": "Their very countenance witnesseth against them; They publish their sin like Sodom; they hide it not; Woe to them, for they bring evil upon themselves!", "webster": "The show of their countenance doth witness against them; and they declare their sin as Sodom, they hide [it] not. Woe to their soul! for they have rewarded evil to themselves.", "vulgate": "agnitio vultus eorum respondit eis et peccatum suum quasi Sodomae praedicaverunt nec absconderunt vae animae eorum quoniam reddita sunt eis mala;", "brenton": "Wherefore now their glory has been brought low, and the shame of their countenance has withstood them, and they have proclaimed their sin as Sodom, and made it manifest."}}, {"v": 10, "ref": "3:10", "o": "אִמְר֥וּ צַדִּ֖יק כִּי ט֑וֹב כִּֽי פְרִ֥י מַעַלְלֵי/הֶ֖ם יֹאכֵֽלוּ", "en": {"kjv": "Say ye to the righteous, that it shall be well with him: for they shall eat the fruit of their doings.", "web": "Tell the righteous “Good!” For they shall eat the fruit of their deeds.", "bsb": "Tell the righteous it will be well with them, for they will enjoy the fruit of their labor.", "asv": "Say ye of the righteous, that it shall be well with him; for they shall eat the fruit of their doings.", "ylt": "Say ye to the righteous, that it is good, Because the fruit of their doings they eat.", "dra": "Say to the just man that it is well, for he shall eat the fruit of his doings.", "bbe": "Happy is the upright man! for he will have joy of the fruit of his ways.", "geneva": "Say ye, Surely it shalbe well with the iust: for they shall eate the fruite of their workes.", "wycliffe": "Seie ye to the iust man, that it schal be to hym wel; for he schal ete the fruyt of hise fyndyngis.", "rotherham": "Say ye to the righteous It is well! For the fruit of their doings, shall they eat:", "darby": "Say ye of the righteous that it shall be well [with him], for they shall eat the fruit of their doings.", "twenty": "", "jps": "Say ye of the righteous, that it shall be well with him; for they shall eat the fruit of their doings.", "acv": "Say ye of the righteous, that it is well, for they shall eat the fruit of their doings.", "anderson": "", "haweis": "", "noyes": "Say ye of the righteous that it shall be well with him, For he shall eat the fruit of his doings.", "webster": "Say ye to the righteous, that [it shall be] well [with him]: for they shall eat the fruit of their doings.", "vulgate": "dicite iusto quoniam bene quoniam fructum adinventionum suarum comedet;", "brenton": "Woe to their soul, for they have devised an evil counsel against themselves, saying against themselves, Let us bind the just, for he is burdensome to us: therefore shall they eat the fruits of their works."}}, {"v": 11, "ref": "3:11", "o": "א֖וֹי לְ/רָשָׁ֣ע רָ֑ע כִּֽי גְמ֥וּל יָדָ֖י/ו יֵעָ֥שֶׂה לּֽ/וֹ", "en": {"kjv": "Woe unto the wicked! it shall be ill with him: for the reward of his hands shall be given him.", "web": "Woe to the wicked! Disaster is upon them; for the deeds of his hands will be paid back to him.", "bsb": "Woe to the wicked; disaster is upon them! For they will be repaid with what their hands have done.", "asv": "Woe unto the wicked! it shall be ill with him; for what his hands have done shall be done unto him.", "ylt": "Woe to the wicked--evil, Because the deed of his hand is done to him.", "dra": "Woe to the wicked unto evil: for the reward of his hands shall be given him.", "bbe": "Unhappy is the sinner! for the reward of his evil doings will come on him.", "geneva": "Woe be to the wicked, it shalbe euill with him: for the reward of his handes shalbe giuen him.", "wycliffe": "Wo to the wickid man in to yuel; for whi the yeldyng of hise hondis schal be maad to hym.", "rotherham": "Alas! for the lawless, it is ill, For what his own hand hath matured, shall be done to him.", "darby": "Woe unto the wicked! it shall be ill [with him], because the desert of his hands shall be rendered unto him.", "twenty": "", "jps": "Woe unto the wicked! it shall be ill with him; for the work of his hands shall be done to him.", "acv": "Woe to the wicked! It is ill with him, for what his hands have done shall be done to him.", "anderson": "", "haweis": "", "noyes": "Woe to the wicked, it shall be ill with him, For the work of his hands shall be repaid him!", "webster": "Woe to the wicked! [it shall be] ill [with him]: for the reward of his hands shall be given him.", "vulgate": "vae impio in malum retributio enim manuum eius fiet ei;", "brenton": "Woe to the transgressor! evils shall happen to him according to the works of his hands."}}, {"v": 12, "ref": "3:12", "o": "עַמִּ/י֙ נֹגְשָׂ֣י/ו מְעוֹלֵ֔ל וְ/נָשִׁ֖ים מָ֣שְׁלוּ ב֑/וֹ עַמִּ/י֙ מְאַשְּׁרֶ֣י/ךָ מַתְעִ֔ים וְ/דֶ֥רֶךְ אֹֽרְחֹתֶ֖י/ךָ בִּלֵּֽעוּ", "en": {"kjv": "As for my people, children are their oppressors, and women rule over them. O my people, they which lead thee cause thee to err, and destroy the way of thy paths.", "web": "As for my people, children are their oppressors, and women rule over them. My people, those who lead you cause you to err, and destroy the way of your paths.", "bsb": "Youths oppress My people, and women rule over them. O My people, your guides mislead you; they turn you from your paths.", "asv": "As for my people, children are their oppressors, and women rule over them. O my people, they that lead thee cause thee to err, and destroy the way of thy paths.", "ylt": "My people--its exactors are sucklings, And women have ruled over it. My people--thy eulogists are causing to err, And the way of thy paths swallowed up.", "dra": "As for my people, their oppressors have stripped them, and women have ruled over them. O my people, they that call thee blessed, the same deceive thee, and destroy the way of thy steps.", "bbe": "As for my people, their ruler is acting like a child, and those who have authority over them are women. O my people, your guides are the cause of your wandering, turning your footsteps out of the right way.", "geneva": "Children are extortioners of my people, and women haue rule ouer them: O my people, they that leade thee, cause thee to erre, and destroy the way of thy paths.", "wycliffe": "The wrongful axeris of my puple robbiden it, and wymmen weren lordis therof. Mi puple, thei that seien thee blessid, disseyuen thee, and distrien the weie of thi steppis.", "rotherham": "My people! children, are their tyrants, And, women, rule over them,—My people! they who should lead thee forward, are causing thee to stray, Thy pathways, have they destroyed,", "darby": "[As for] my people, children are their oppressors, and women rule over them. My people! they that guide thee mislead [thee], and destroy the way of thy paths.", "twenty": "", "jps": "As for My people, a babe is their master, and women rule over them. O My people, they that lead thee cause thee to err, and destroy the way of thy paths.", "acv": "As for my people, children are their oppressors, and women rule over them. O my people, those who lead thee cause thee to err, and destroy the way of thy paths.", "anderson": "", "haweis": "", "noyes": "As for my people, children are their oppressors, And women rule over them. O my people, thy leaders cause thee to err, And destroy the way in which thou walkest!", "webster": "[As for] my people, children [are] their oppressors, and women rule over them. O my people, they who lead thee cause [thee] to err, and destroy the way of thy paths.", "vulgate": "populum meum exactores sui spoliaverunt et mulieres dominatae sunt eius popule meus qui beatum te dicunt ipsi te decipiunt et viam gressuum tuorum dissipant;", "brenton": "O my people, your exactors strip you, and extortioners rule over you: O my people, they that pronounce you blesses lead you astray, and pervert the path of your feet."}}, {"v": 13, "ref": "3:13", "o": "נִצָּ֥ב לָ/רִ֖יב יְהוָ֑ה וְ/עֹמֵ֖ד לָ/דִ֥ין עַמִּֽים", "en": {"kjv": "The Lord standeth up to plead, and standeth to judge the people.", "web": "Yahweh stands up to contend, and stands to judge the peoples.", "bsb": "The LORD arises to contend; He stands to judge the people.", "asv": "Jehovah standeth up to contend, and standeth to judge the peoples.", "ylt": "Jehovah hath stood up to plead, And He is standing to judge the peoples.", "dra": "The Lord standeth up to judge, and he standeth to judge the people.", "bbe": "The Lord is ready to take up his cause against his people, and is about to come forward as their judge.", "geneva": "The Lord standeth vp to pleade, yea, hee standeth to iudge the people.", "wycliffe": "The Lord stondith for to deme, and `the Lord stondith for to deme puplis;", "rotherham": "Yahweh hath taken his station to plead,—And is standing to judge peoples:", "darby": "Jehovah setteth himself to plead, and standeth to judge the peoples.", "twenty": "", "jps": "HaShem standeth up to plead, and standeth to judge the peoples.", "acv": "Jehovah stands up to contend, and stands to judge the peoples.", "anderson": "", "haweis": "", "noyes": "Jehovah standeth up to maintain his cause; He standeth up to judge his people.", "webster": "The LORD standeth up to plead, and standeth to judge the people.", "vulgate": "stat ad iudicandum Dominus et stat ad iudicandos populos;", "brenton": "But now the Lord will stand up for judgment, and will enter into judgment with his people."}}, {"v": 14, "ref": "3:14", "o": "יְהוָה֙ בְּ/מִשְׁפָּ֣ט יָב֔וֹא עִם זִקְנֵ֥י עַמּ֖/וֹ וְ/שָׂרָ֑י/ו וְ/אַתֶּם֙ בִּֽעַרְתֶּ֣ם הַ/כֶּ֔רֶם גְּזֵלַ֥ת הֶֽ/עָנִ֖י בְּ/בָתֵּי/כֶֽם", "en": {"kjv": "The Lord will enter into judgment with the ancients of his people, and the princes thereof: for ye have eaten up the vineyard; the spoil of the poor is in your houses.", "web": "Yahweh will enter into judgment with the elders of his people, and their leaders: “It is you who have eaten up the vineyard. The plunder of the poor is in your houses.", "bsb": "The LORD brings this charge against the elders and leaders of His people: “You have devoured the vineyard; the plunder of the poor is in your houses.", "asv": "Jehovah will enter into judgment with the elders of his people, and the princes thereof: It is ye that have eaten up the vineyard; the spoil of the poor is in your houses:", "ylt": "Jehovah into judgment doth enter With elders of His people, and its heads: `And ye, ye have consumed the vineyard, Plunder of the poor is in your houses.", "dra": "The Lord will enter into judgment with the ancients of his people, and its princes: for you have devoured the vineyard, and the spoil of the poor is in your house.", "bbe": "The Lord comes to be the judge of their responsible men and of their rulers: it is you who have made waste the vine-garden, and in your houses is the property of the poor which you have taken by force.", "geneva": "The Lord shall enter into iudgement with the Ancients of his people and the princes thereof: for ye haue eaten vp the vineyarde: the spoyle of the poore is in your houses.", "wycliffe": "the Lord schal come to doom, with the eldere men of his puple, and with hise princes; for ye han wastid my vyner, and the raueyn of a pore man is in youre hous.", "rotherham": "Yahweh, into judgment, will enter, With the elders of his people And their princes,—But ye, have consumed the vineyard, That which hath been robbed from the oppressed, is in your houses.", "darby": "Jehovah will enter into judgment with the elders of his people and their princes, [saying:] It is ye that have eaten up the vineyard: the spoil of the poor is in your houses.", "twenty": "", "jps": "HaShem will enter into judgment with the elders of His people, and the princes thereof: 'It is ye that have eaten up the vineyard; the spoil of the poor is in your houses;", "acv": "Jehovah will enter into judgment with the elders of his people, and the rulers of it. It is ye who have eaten up the vineyard; the spoil of a poor man is in your houses.", "anderson": "", "haweis": "", "noyes": "Jehovah entereth into judgment with the elders of his people, and their princes: \"So then ye have consumed the vineyard; The plunder of the poor is in your houses!", "webster": "The LORD will enter into judgment with the elders of his people, and with their princes: for ye have eaten up the vineyard; the spoil of the poor [is] in your houses.", "vulgate": "Dominus ad iudicium veniet cum senibus populi sui et principibus eius vos enim depasti estis vineam meam et rapina pauperis in domo vestra;", "brenton": "The Lord himself shall enter into judgment with the elders of the people, and with their rulers: but why have ye set my vineyard on fire, and why is the spoil of the poor in your houses?"}}, {"v": 15, "ref": "3:15", "o": "מ/ל/כם מַה לָּ/כֶם֙ תְּדַכְּא֣וּ עַמִּ֔/י וּ/פְנֵ֥י עֲנִיִּ֖ים תִּטְחָ֑נוּ נְאֻם אֲדֹנָ֥/י יְהוִ֖ה צְבָאֽוֹת", "en": {"kjv": "What mean ye that ye beat my people to pieces, and grind the faces of the poor? saith the Lord God of hosts.", "web": "What do you mean that you crush my people, and grind the face of the poor?” says the Lord, Yahweh of Armies.", "bsb": "Why do you crush My people and grind the faces of the poor?” declares the Lord GOD of Hosts.", "asv": "what mean ye that ye crush my people, and grind the face of the poor? saith the Lord, Jehovah of hosts.", "ylt": "What--to you? ye bruise My people, And the faces of the poor ye grind.' An affirmation of the Lord, Jehovah of Hosts, And Jehovah saith:", "dra": "Why do you consume my people, and grind the faces of the poor? saith the Lord the God of hosts.", "bbe": "By what right are you crushing my people, and putting a bitter yoke on the necks of the poor? This is the word of the Lord, the Lord of armies.", "geneva": "What haue ye to do, that ye beate my people to pieces, and grinde the faces of the poore, saith the Lord, euen the Lord of hoasts?", "wycliffe": "Whi al to-breken ye my puple, and grynden togidere the faces of pore men? seith the Lord God of oostis.", "rotherham": "What right have ye to crush my people, And the faces of the oppressed, to grind? Demandeth My Lord Yahweh of hosts—And Yahweh saith—", "darby": "What mean ye that ye crush my people, and grind the faces of the afflicted? saith the Lord, Jehovah of hosts.", "twenty": "", "jps": "What mean ye that ye crush My people, and grind the face of the poor?' saith the L-rd, the GOD of hosts.", "acv": "What do ye mean that ye crush my people, and grind the face of the poor? says the Lord, Jehovah of hosts.", "anderson": "", "haweis": "", "noyes": "What mean ye, that ye crush my people, And grind the faces of the poor?\" Saith Jehovah, the Lord of hosts.", "webster": "What mean ye [that] ye beat my people to pieces, and grind the faces of the poor? saith the Lord GOD of hosts.", "vulgate": "quare adteritis populum meum et facies pauperum commolitis dicit Dominus Deus exercituum;", "brenton": "Why do ye wrong my people, and shame the face of the poor?"}}, {"v": 16, "ref": "3:16", "o": "וַ/יֹּ֣אמֶר יְהוָ֗ה יַ֚עַן כִּ֤י גָֽבְהוּ֙ בְּנ֣וֹת צִיּ֔וֹן וַ/תֵּלַ֨כְנָה֙ נטוות נְטוּי֣וֹת גָּר֔וֹן וּֽ/מְשַׂקְּר֖וֹת עֵינָ֑יִם הָל֤וֹךְ וְ/טָפֹף֙ תֵּלַ֔כְנָה וּ/בְ/רַגְלֵי/הֶ֖ם תְּעַכַּֽסְנָה", "en": {"kjv": "Moreover the Lord saith, Because the daughters of Zion are haughty, and walk with stretched forth necks and wanton eyes, walking and mincing as they go, and making a tinkling with their feet:", "web": "Moreover Yahweh said, “Because the daughters of Zion are haughty, and walk with outstretched necks and flirting eyes, walking to trip as they go, jingling ornaments on their feet;", "bsb": "The LORD also says: “Because the daughters of Zion are haughty— walking with heads held high and wanton eyes, prancing and skipping as they go, jingling the bracelets on their ankles—", "asv": "Moreover Jehovah said, Because the daughters of Zion are haughty, and walk with outstretched necks and wanton eyes, walking and mincing as they go, and making a tinkling with their feet;", "ylt": "`Because that daughters of Zion have been haughty, And they walk stretching out the neck, And deceiving with the eyes, Walking and mincing they go, And with their feet they make a tinkling,", "dra": "And the Lord said: Because the daughters of Sion are haughty, and have walked with stretched out necks, and wanton glances of their eyes, and made a noise as they walked with their feet and moved in a set pace:", "bbe": "Again, the Lord has said, Because the daughters of Zion are full of pride, and go with outstretched necks and wandering eyes, with their foot-chains sounding when they go:", "geneva": "The Lord also saith, Because the daughters of Zion are hautie, and walke with stretched out neckes, and with wandering eyes, walking and minsing as they goe, and making a tinkeling with their feete,", "wycliffe": "And the Lord God seide, For that that the douytris of Syon weren reisid, and yeden with a necke stretchid forth, and yeden bi signes of iyen, and flappiden with hondis, and yeden, and with her feet yeden in wel araied goyng,", "rotherham": "Because haughty are the daughters of Zion, And they walk with neck thrown back, and wanton eyes,—Tripping along as they go, And with their feet, making, a tinkling sound,", "darby": "And Jehovah said, Because the daughters of Zion are haughty, and walk with stretched-out neck and wanton eyes, and go along mincing, and making a tinkling with their feet;", "twenty": "", "jps": "Moreover HaShem said: because the daughters of Zion are haughty, and walk with stretched-forth necks and wanton eyes, walking and mincing as they go, and making a tinkling with their feet;", "acv": "Moreover Jehovah said, Because the daughters of Zion are haughty, and walk with outstretched necks and wanton eyes, walking and mincing as they go, and making a tinkling with their feet,", "anderson": "", "haweis": "", "noyes": "Thus, also, saith Jehovah: Because the daughters of Zion are haughty, And walk with outstretched necks, And glance their eyes wantonly, Mincing their steps as they go, And tinkling with their foot-clasps,", "webster": "Moreover the LORD saith, Because the daughters of Zion are haughty, and walk with extended necks and wanton eyes, walking and mincing [as] they go, and making a tinkling with their feet:", "vulgate": "et dixit Dominus pro eo quod elevatae sunt filiae Sion et ambulaverunt extento collo et nutibus oculorum ibant et plaudebant ambulabant et in pedibus suis conposito gradu incedebant;", "brenton": "Thus saith the Lord, Because the daughters of Sion are haughty, and have walked with an outstretched neck, and with winking of the eyes, and motion of the feet, at the same time drawing their garments in trains, and at the same time sporting with their feet:"}}, {"v": 17, "ref": "3:17", "o": "וְ/שִׂפַּ֣ח אֲדֹנָ֔/י קָדְקֹ֖ד בְּנ֣וֹת צִיּ֑וֹן וַ/יהוָ֖ה פָּתְ/הֵ֥ן יְעָרֶֽה", "en": {"kjv": "Therefore the Lord will smite with a scab the crown of the head of the daughters of Zion, and the Lord will discover their secret parts.", "web": "therefore the Lord brings sores on the crown of the head of the women of Zion, and Yahweh will make their scalps bald.”", "bsb": "the Lord will bring sores on the heads of the daughters of Zion, and the LORD will make their foreheads bare.”", "asv": "therefore the Lord will smite with a scab the crown of the head of the daughters of Zion, and Jehovah will lay bare their secret parts.", "ylt": "The Lord also hath scabbed The crown of the head of daughters of Zion, And Jehovah their simplicity exposeth.", "dra": "The Lord will make bald the crown of the head of the daughters of Sion, and the Lord will discover their hair.", "bbe": "The Lord will send disease on the heads of the daughters of Zion, and the Lord will let their secret parts be seen.", "geneva": "Therefore shall the Lord make the heades of the daughters of Zion balde, and the Lord shall discouer their secrete partes.", "wycliffe": "the Lord schal make ballyd the nol of the douytris of Sion, and the Lord schal make nakid the heer of hem.", "rotherham": "Therefore will My Lord, smite with leprosy the crown of hair of the daughters of Zion,—And, as for Yahweh, their shame, will he lay bare!", "darby": "therefore the Lord will make bald the crown of the head of the daughters of Zion, and Jehovah will lay bare their secret parts.", "twenty": "", "jps": "Therefore the L-rd will smite with a scab the crown of the head of the daughters of Zion, and HaShem will lay bare their secret parts.", "acv": "therefore the Lord will smite with a scab the crown of the head of the daughters of Zion, and Jehovah will lay bare their secret parts.", "anderson": "", "haweis": "", "noyes": "Therefore will the Lord make their heads bald, And Jehovah will expose their nakedness.", "webster": "Therefore the Lord will smite with a scab the crown of the head of the daughters of Zion, and the LORD will uncover their secret parts.", "vulgate": "decalvabit Dominus verticem filiarum Sion et Dominus crinem earum nudabit;", "brenton": "therefore the Lord will humble the chief daughters of Sion, and the Lord will expose their form in that day;"}}, {"v": 18, "ref": "3:18", "o": "בַּ/יּ֨וֹם הַ/ה֜וּא יָסִ֣יר אֲדֹנָ֗/י אֵ֣ת תִּפְאֶ֧רֶת הָ/עֲכָסִ֛ים וְ/הַ/שְּׁבִיסִ֖ים וְ/הַ/שַּׂהֲרֹנִֽים", "en": {"kjv": "In that day the Lord will take away the bravery of their tinkling ornaments about their feet, and their cauls, and their round tires like the moon,", "web": "In that day the Lord will take away the beauty of their anklets, the headbands, the crescent necklaces,", "bsb": "In that day the Lord will take away their finery: their anklets and headbands and crescents;", "asv": "In that day the Lord will take away the beauty of their anklets, and the cauls, and the crescents;", "ylt": "In that day doth the Lord turn aside The beauty of the tinkling ornaments, And of the embroidered works, And of the round tires like moons,", "dra": "In that day the Lord will take away the ornaments of shoes, and little moons,", "bbe": "In that day the Lord will take away the glory of their foot-rings, and their sun-jewels, and their moon-ornaments,", "geneva": "In that day shall the Lord take away the ornament of the slippers, and the calles, and the round tyres,", "wycliffe": "In that dai the Lord schal take awei the ournement of schoon, and goldun litle bellis lijk the moone,", "rotherham": "In that day, will My Lord remove the finery—of the anklets, and the little suns and the little moons;", "darby": "In that day the Lord will take away the ornament of anklets, and the little suns and crescents,", "twenty": "", "jps": "In that day the L-rd will take away the bravery of their anklets, and the fillets, and the crescents;", "acv": "In that day the Lord will take away the beauty of their anklets, and the hair nets, and the crescents,", "anderson": "", "haweis": "", "noyes": "In that day shall the Lord take from them The ornaments of the foot-clasps, and the net-works, and the crescents;", "webster": "In that day the Lord will take away the show of [their] tinkling ornaments [about their feet], and [their] cauls, and [their] round tires like the moon.", "vulgate": "in die illa auferet Dominus ornatum calciamentorum et lunulas;", "brenton": "and the Lord will take away the glory of their raiment, the curls and the fringes, and the crescents,"}}, {"v": 19, "ref": "3:19", "o": "הַ/נְּטִיפ֥וֹת וְ/הַ/שֵּׁיר֖וֹת וְ/הָֽ/רְעָלֽוֹת", "en": {"kjv": "The chains, and the bracelets, and the mufflers,", "web": "the earrings, the bracelets, the veils,", "bsb": "their pendants, bracelets, and veils;", "asv": "the pendants, and the bracelets, and the mufflers;", "ylt": "Of the drops, and the bracelets, and the mufflers,", "dra": "And chains and necklaces, and bracelets, and bonnets,", "bbe": "The ear-rings, and the chains, and the delicate clothing,", "geneva": "The sweete balles, and the brasselets, and the bonnets,", "wycliffe": "and ribans, and brochis, and ournementis of armes nyy the schuldris, and mytris, ether chapelettis,", "rotherham": "the pendants and the bracelets and the veils;", "darby": "the pearl-drops, and the bracelets, and the veils,", "twenty": "", "jps": "the pendants, and the bracelets, and the veils;", "acv": "the pendants, and the bracelets, and the mufflers,", "anderson": "", "haweis": "", "noyes": "The ear-rings, and the bracelets, and the veils;", "webster": "The chains, and the bracelets, and the mufflers,", "vulgate": "et torques et monilia et armillas et mitras;", "brenton": "and the chains, and the ornaments of their faces,"}}, {"v": 20, "ref": "3:20", "o": "הַ/פְּאֵרִ֤ים וְ/הַ/צְּעָדוֹת֙ וְ/הַ/קִּשֻּׁרִ֔ים וּ/בָתֵּ֥י הַ/נֶּ֖פֶשׁ וְ/הַ/לְּחָשִֽׁים", "en": {"kjv": "The bonnets, and the ornaments of the legs, and the headbands, and the tablets, and the earrings,", "web": "the headdresses, the ankle chains, the sashes, the perfume bottles, the charms,", "bsb": "their headdresses, ankle chains, and sashes; their perfume bottles and charms;", "asv": "the headtires, and the ankle chains, and the sashes, and the perfume-boxes, and the amulets;", "ylt": "Of the bonnets, and the ornaments of the legs, And of the bands, And of the perfume boxes, and the amulets,", "dra": "And bodkins, and ornaments of the legs, and tablets, and sweet balls, and earrings,", "bbe": "The head-bands, and the arm-chains, and the worked bands, and the perfume-boxes, and the jewels with secret powers,", "geneva": "The tyres of the head, and the sloppes, and the head bandes, and the tablets, and the earings,", "wycliffe": "and coombis, and ournementis of armes niy the hondis, and goldun ourenementis lijk laumpreis, and litil vessels of oynementis,", "rotherham": "the chaplets and the armlets and the girdles, and the scent-cases, and the amulets;", "darby": "the head-dresses, and the stepping chains, and the girdles, and the scent-boxes, and the amulets;", "twenty": "", "jps": "the headtires, and the armlets, and the sashes, and the corselets, and the amulets;", "acv": "the bonnets, and the ankle chains, and the sashes, and the perfume-boxes, and the amulets,", "anderson": "", "haweis": "", "noyes": "The turbans, and the ankle-chains, and the belts; The perfume-boxes, and the amulets;", "webster": "The bonnets, and the ornaments of the legs, and the head-bands, and the tablets, and the ear-rings,", "vulgate": "discriminalia et periscelidas et murenulas et olfactoriola et inaures;", "brenton": "and the array of glorious ornaments, and the armlets, and the bracelets, and the wreathed work, and the finger-rings, and the ornaments for the right hand,"}}, {"v": 21, "ref": "3:21", "o": "הַ/טַּבָּע֖וֹת וְ/נִזְמֵ֥י הָ/אָֽף", "en": {"kjv": "The rings, and nose jewels,", "web": "the signet rings, the nose rings,", "bsb": "their signet rings and nose rings;", "asv": "the rings, and the nose-jewels;", "ylt": "Of the seals, and of the nose-rings,", "dra": "And rings, and jewels hanging on the forehead,", "bbe": "The rings, and the nose-jewels,", "geneva": "The rings and the mufflers,", "wycliffe": "and eere ryngis, and ryngis, and preciouse stoonys hangynge in the forheed,", "rotherham": "the rings and the nose-jewels;", "darby": "the finger-rings, and the nose-rings;", "twenty": "", "jps": "the rings, and the nose-jewels;", "acv": "the rings, and the nose-jewels,", "anderson": "", "haweis": "", "noyes": "The finger-rings, and the nose-jewels;", "webster": "The rings, and nose-jewels,", "vulgate": "et anulos et gemmas in fronte pendentes;", "brenton": "and the ear-rings, and the garments with scarlet borders, and the garments with purple grounds, and the shawls to be worn in the house, and the Spartan transparent dresses, and those made of fine linen, and the purple ones, and the scarlet ones, and the fine linen, interwoven with gold and purple, and the light coverings for couches."}}, {"v": 22, "ref": "3:22", "o": "הַ/מַּֽחֲלָצוֹת֙ וְ/הַ/מַּ֣עֲטָפ֔וֹת וְ/הַ/מִּטְפָּח֖וֹת וְ/הָ/חֲרִיטִֽים", "en": {"kjv": "The changeable suits of apparel, and the mantles, and the wimples, and the crisping pins,", "web": "the fine robes, the capes, the cloaks, the purses,", "bsb": "their festive robes, capes, cloaks, and purses;", "asv": "the festival robes, and the mantles, and the shawls, and the satchels;", "ylt": "Of the costly apparel, and of the mantles, And of the coverings, and of the purses,", "dra": "And changes of apparel, and short cloaks, and fine linen, and crisping pins,", "bbe": "The feast-day dresses, and the robes, and the wide skirts, and the handbags,", "geneva": "The costly apparell and the vailes, and the wimples, and the crisping pinnes,", "wycliffe": "and chaungynge clothis, and mentils, and schetis, ether smockis, and needlis,", "rotherham": "the robes, and the over-tunics, and the cloaks and the purses;", "darby": "the festival-robes, and the tunics, and the mantles, and the wallets;", "twenty": "", "jps": "the aprons, and the mantelets, and the cloaks, and the girdles;", "acv": "the festival robes, and the mantles, and the shawls, and the satchels,", "anderson": "", "haweis": "", "noyes": "The embroidered robes, and the tunics, and the cloaks, and the purses;", "webster": "The changeable suits of apparel, and the mantles, and the wimples, and the crisping-pins,", "vulgate": "et mutatoria et pallia et linteamina et acus;", "brenton": "And there shall be instead of a sweet smell, dust; and instead of a girdle, thou shalt gird thyself with a rope; and instead of a golden ornament for the head, thou shalt have baldness on account of thy works; and instead of a tunic with a scarlet ground, thou shalt gird thyself with sackcloth."}}, {"v": 23, "ref": "3:23", "o": "וְ/הַ/גִּלְיֹנִים֙ וְ/הַ/סְּדִינִ֔ים וְ/הַ/צְּנִיפ֖וֹת וְ/הָ/רְדִידִֽים", "en": {"kjv": "The glasses, and the fine linen, and the hoods, and the vails.", "web": "the hand mirrors, the fine linen garments, the tiaras, and the shawls.", "bsb": "and their mirrors, linen garments, tiaras, and shawls.", "asv": "the hand-mirrors, and the fine linen, and the turbans, and the veils.", "ylt": "Of the mirrors, and of the linen garments, And of the hoods, and of the vails,", "dra": "And lookingglasses, and lawns, and headbands, and fine veils.", "bbe": "The looking-glasses, and the fair linen, and the high head-dresses, and the veils.", "geneva": "And the glasses and the fine linen, and the hoodes, and the launes.", "wycliffe": "and myrouris, and smal lynun clothis aboute the schuldris, and kercheues, and roketis.", "rotherham": "and the mirrors and the linen wraps, and the tiaras and the cloaks.", "darby": "the mirrors, and the fine linen bodices, and the turbans, and the flowing veils.", "twenty": "", "jps": "and the gauze robes, and the fine linen, and the turbans, and the mantles.", "acv": "the hand-mirrors, and the fine linen, and the turbans, and the veils.", "anderson": "", "haweis": "", "noyes": "The mirrors, and the linen shifts, and the head-bands, and the large veils.", "webster": "The glasses, and the fine linen, and the hoods, and the vails.", "vulgate": "et specula et sindones et vittas et theristra;", "brenton": "And thy most beautiful son whom thou lovest shall fall by the sword; and your mighty men shall fall by the sword, and shall be brought low."}}, {"v": 24, "ref": "3:24", "o": "וְ/הָיָה֩ תַ֨חַת בֹּ֜שֶׂם מַ֣ק יִֽהְיֶ֗ה וְ/תַ֨חַת חֲגוֹרָ֤ה נִקְפָּה֙ וְ/תַ֨חַת מַעֲשֶׂ֤ה מִקְשֶׁה֙ קָרְחָ֔ה וְ/תַ֥חַת פְּתִיגִ֖יל מַחֲגֹ֣רֶת שָׂ֑ק כִּי תַ֖חַת יֹֽפִי", "en": {"kjv": "And it shall come to pass, that instead of sweet smell there shall be stink; and instead of a girdle a rent; and instead of well set hair baldness; and instead of a stomacher a girding of sackcloth; and burning instead of beauty.", "web": "It shall happen that instead of sweet spices, there shall be rottenness; instead of a belt, a rope; instead of well set hair, baldness; instead of a robe, a wearing of sackcloth; and branding instead of beauty.", "bsb": "Instead of fragrance there will be a stench; instead of a belt, a rope; instead of styled hair, baldness; instead of fine clothing, sackcloth; instead of beauty, shame.", "asv": "And it shall come to pass, that instead of sweet spices there shall be rottenness; and instead of a girdle, a rope; and instead of well set hair, baldness; and instead of a robe, a girding of sackcloth; branding instead of beauty.", "ylt": "And it hath been, instead of spice is muck, And instead of a girdle, a rope, And instead of curled work, baldness, And instead of a stomacher a girdle of sackcloth.", "dra": "And instead of a sweet smell there shall be stench, and instead of a girdle, a cord, and instead of curled hair, baldness, and instead of a stomacher, haircloth.", "bbe": "And in the place of sweet spices will be an evil smell, and for a fair band a thick cord; for a well-dressed head there will be the cutting-off of the hair, and for a beautiful robe there will be the clothing of sorrow; the mark of the prisoner in place of the ornaments of the free.", "geneva": "And in steade of sweete sauour, there shall be stinke, and in steade of a girdle, a rent, and in steade of dressing of the heare, baldnesse, and in steade of a stomacher, a girding of sackecloth, and burning in steade of beautie.", "wycliffe": "And stynk shal be for swete odour, and a corde for the girdil; ballidnesse schal be for crispe heer, and an heire for a brest girdil.", "rotherham": "And it shall come to pass—That instead of fragrance, a putrid odour, shall be, And instead of a girdle, an encircling rope, And instead of braided hair, baldness, And instead of a festal robe, a girding of sackcloth, Branding instead of beauty:", "darby": "And it shall come to pass, instead of perfume there shall be rottenness; and instead of a girdle, a rope; and instead of well-set hair, baldness; and instead of a robe of display, a girding of sackcloth; brand instead of beauty.", "twenty": "", "jps": "And it shall come to pass, that instead of sweet spices there shall be rottenness; and instead of a girdle rags; and instead of curled hair baldness; and instead of a stomacher a girding of sackcloth; branding instead of beauty.", "acv": "And it shall come to pass, that instead of sweet spices there shall be rottenness, and instead of a girdle, a rope, and instead of well set hair, baldness, and instead of a robe, a girding of sackcloth, branding instead of beauty.", "anderson": "", "haweis": "", "noyes": "And instead of perfume there shall be corruption; Instead of a belt, a rope; Instead of curled locks, baldness; Instead of a wide mantle, a covering of sackcloth; Fire-scars instead of beauty.", "webster": "And it shall come to pass, [that] instead of sweet smell there shall be an offensive odor; and instead of a girdle a rent; and instead of well set hair baldness; and instead of a stomacher a girding of sackcloth; [and] burning instead of beauty.", "vulgate": "et erit pro suavi odore fetor et pro zona funiculus et pro crispanti crine calvitium et pro fascia pectorali cilicium;", "brenton": "And the stores of your ornaments shall mourn, and thou shalt be left alone, and shalt be levelled with the ground."}}, {"v": 25, "ref": "3:25", "o": "מְתַ֖יִ/ךְ בַּ/חֶ֣רֶב יִפֹּ֑לוּ וּ/גְבוּרָתֵ֖/ךְ בַּ/מִּלְחָמָֽה", "en": {"kjv": "Thy men shall fall by the sword, and thy mighty in the war.", "web": "Your men shall fall by the sword, and your mighty in the war.", "bsb": "Your men will fall by the sword, and your warriors in battle.", "asv": "Thy men shall fall by the sword, and thy mighty in the war.", "ylt": "For instead of glory, thy men by sword do fall, And thy might in battle.", "dra": "Thy fairest men also shall fall by the sword, and thy valiant ones in battle.", "bbe": "Your men will be put to the sword, and your men of war will come to destruction in the fight.", "geneva": "Thy men shall fall by the sworde, and thy strength in the battell.", "wycliffe": "Also thi faireste men schulen falle bi swerd, and thi stronge men schulen falle in batel.", "rotherham": "Thy males, by the sword shall fall,—And, thy mighty men, by the war;", "darby": "Thy men shall fall by the sword, and thy mighty in the fight;", "twenty": "", "jps": "Thy men shall fall by the sword, and thy mighty in the war.", "acv": "Thy men shall fall by the sword, and thy mighty in the war.", "anderson": "", "haweis": "", "noyes": "Thy men shall fall by the sword, Yea, thy mighty men in battle;", "webster": "Thy men shall fall by the sword, and thy mighty in the war.", "vulgate": "pulcherrimi quoque viri tui gladio cadent et fortes tui in proelio;", "brenton": ""}}, {"v": 26, "ref": "3:26", "o": "וְ/אָנ֥וּ וְ/אָבְל֖וּ פְּתָחֶ֑י/הָ וְ/נִקָּ֖תָה לָ/אָ֥רֶץ תֵּשֵֽׁב", "en": {"kjv": "And her gates shall lament and mourn; and she being desolate shall sit upon the ground.", "web": "Her gates shall lament and mourn; and she shall be desolate and sit on the ground.", "bsb": "And the gates of Zion will lament and mourn; destitute, she will sit on the ground.", "asv": "And her gates shall lament and mourn; and she shall be desolate and sit upon the ground.", "ylt": "And lamented and mourned have her openings, Yea, she hath been emptied, on the earth she sitteth!", "dra": "And her gates shall lament and mourn, and she shall sit desolate on the ground.", "bbe": "And in the public places of her towns will be sorrow and weeping; and she will be seated on the earth, waste and uncovered.", "geneva": "Then shall her gates mourne and lament, and she, being desolate, shall sit vpon the ground.", "wycliffe": "And the yatis therof schulen weile, and morene; and it schal sitte desolat in erthe.", "rotherham": "And her gates shall mourn and lament,—And forsaken, on the ground, shall she sit.", "darby": "and her gates shall lament and mourn; and, stripped, she shall sit upon the ground.", "twenty": "", "jps": "And her gates shall lament and mourn; and utterly bereft she shall sit upon the ground.", "acv": "And her gates shall lament and mourn, and she shall be desolate and sit upon the ground.", "anderson": "", "haweis": "", "noyes": "Her gates shall lament and mourn, And she, being desolate, shall sit upon the ground.", "webster": "And her gates shall lament and mourn; and she [being] desolate, shall sit upon the ground.", "vulgate": "et maerebunt atque lugebunt portae eius et desolata in terra sedebit;", "brenton": ""}}]}, {"c": 4, "verses": [{"v": 1, "ref": "4:1", "o": "וְ/הֶחֱזִיקוּ֩ שֶׁ֨בַע נָשִׁ֜ים בְּ/אִ֣ישׁ אֶחָ֗ד בַּ/יּ֤וֹם הַ/הוּא֙ לֵ/אמֹ֔ר לַחְמֵ֣/נוּ נֹאכֵ֔ל וְ/שִׂמְלָתֵ֖/נוּ נִלְבָּ֑שׁ רַ֗ק יִקָּרֵ֤א שִׁמְ/ךָ֙ עָלֵ֔י/נוּ אֱסֹ֖ף חֶרְפָּתֵֽ/נוּ", "en": {"kjv": "And in that day seven women shall take hold of one man, saying, We will eat our own bread, and wear our own apparel: only let us be called by thy name, to take away our reproach.", "web": "Seven women shall take hold of one man in that day, saying, “We will eat our own bread, and wear our own clothing: only let us be called by your name. Take away our reproach.”", "bsb": "In that day seven women will take hold of one man and say, “We will eat our own bread and provide our own clothes. Just let us be called by your name. Take away our disgrace!”", "asv": "And seven women shall take hold of one man in that day, saying, We will eat our own bread, and wear our own apparel: only let us be called by thy name; take thou away our reproach.", "ylt": "And taken hold have seven women on one man, In that day, saying, `Our own bread we do eat, And our own raiment we put on, Only, let thy name be called over us, Remove thou our reproach.'", "dra": "And in that day seven women shall take hold of one man, saying: We will eat our own bread, and wear our own apparel: only let us be called by thy name, take away our reproach.", "bbe": "And in that day seven women will put their hands on one man, saying, There will be no need for you to give us food or clothing, only let us go under your name, so that our shame may be taken away.", "geneva": "And in that day shall seuen women take hold of one man, saying, Wee will eate our owne bread, and we wil weare our owne garments: onely let vs bee called by thy name, and take away our reproche.", "wycliffe": "And seuene wymmen schulen catche o man in that dai, and schulen seie, We schulen ete oure breed, and we schulen be hilid with oure clothis; oneli thi name be clepid on vs, do thou awei oure schenschip.", "rotherham": "And seven women will take hold of one man in that day, saying, Our own bread, will we eat, And our own apparel, will we wear,—Only let us be called by thy name, to take away our reproach.", "darby": "And seven women shall take hold of one man in that day, saying, Our own bread will we eat, and with our own garments will we be clothed; only let us be called by thy name; — take away our reproach!", "twenty": "", "jps": "And seven women shall take hold of one man in that day, saying: 'We will eat our own bread, and wear our own apparel; only let us be called by thy name; take thou away our reproach.'", "acv": "And seven women shall take hold of one man in that day, saying, We will eat our own bread, and wear our own apparel. Only let us be called by thy name; take thou away our reproach.", "anderson": "", "haweis": "", "noyes": "In that day shall seven women lay hold of one man saying: We will eat our own bread, And wear our own garments, Only let us be called by thy name, And take away our reproach!", "webster": "And in that day seven women shall take hold of one man, saying, We will eat our own bread, and wear our own apparel: only let us be called by thy name, to take away our reproach.", "vulgate": "et adprehendent septem mulieres virum unum in die illa dicentes panem nostrum comedemus et vestimentis nostris operiemur tantummodo vocetur nomen tuum super nos aufer obprobrium nostrum;", "brenton": "And seven women shall take hold of one man, saying, We will eat our own bread, and wear our own raiment: only let thy name be called upon us, and take away our reproach."}}, {"v": 2, "ref": "4:2", "o": "בַּ/יּ֣וֹם הַ/ה֗וּא יִֽהְיֶה֙ צֶ֣מַח יְהוָ֔ה לִ/צְבִ֖י וּ/לְ/כָב֑וֹד וּ/פְרִ֤י הָ/אָ֨רֶץ֙ לְ/גָא֣וֹן וּ/לְ/תִפְאֶ֔רֶת לִ/פְלֵיטַ֖ת יִשְׂרָאֵֽל", "en": {"kjv": "In that day shall the branch of the Lord be beautiful and glorious, and the fruit of the earth shall be excellent and comely for them that are escaped of Israel.", "web": "In that day, Yahweh’s branch will be beautiful and glorious, and the fruit of the land will be the beauty and glory of the survivors of Israel.", "bsb": "On that day the Branch of the LORD will be beautiful and glorious, and the fruit of the land will be the pride and glory of Israel’s survivors.", "asv": "In that day shall the branch of Jehovah be beautiful and glorious, and the fruit of the land shall be excellent and comely for them that are escaped of Israel.", "ylt": "In that day is the Shoot of Jehovah for desire and for honour, And the fruit of the earth For excellence and for beauty to the escaped of Israel.", "dra": "In that day the bud of the Lord shall be in magnificence and glory, and the fruit of the earth shall be high, and a great joy to them that shall have escaped of Israel.", "bbe": "In that day will the young growth of the Lord be beautiful in glory, and the fruit of the earth will be the pride of those who are still living in Israel.", "geneva": "In that day shall the budde of the Lord bee beautifull and glorious, and the fruite of the earth shalbe excellent and pleasant for them that are escaped of Israel.", "wycliffe": "In that dai the buriownyng of the Lord schal be in greet worschip and glorie; and the fruyt of erthe schal be hiy, and ful out ioye `schal be to hem that schulen be sauyd of Israel.", "rotherham": "In that day, Shall the Bud of Yahweh, become beautiful and glorious,—And the Fruit of the Land splendid and majestic, To the escaped of Israel.", "darby": "In that day there shall be a sprout of Jehovah for beauty and glory, and the fruit of the earth for excellency and for ornament for those that are escaped of Israel.", "twenty": "", "jps": "In that day shall the growth of HaShem be beautiful and glorious, and the fruit of the land excellent and comely for them that are escaped of Israel.", "acv": "In that day the branch of Jehovah shall be beautiful and glorious, and the fruit of the land shall be excellent and comely for those who have escaped from Israel.", "anderson": "", "haweis": "", "noyes": "In that day shall the increase of Jehovah be glorious and honorable, And the fruit of the land excellent and beautiful, For them that have escaped of Israel.", "webster": "In that day shall the branch of the LORD be beautiful and glorious, and the fruit of the earth [shall be] excellent and comely for them that have escaped of Israel.", "vulgate": "in die illa erit germen Domini in magnificentia et in gloria et fructus terrae sublimis et exultatio his qui salvati fuerint de Israhel;", "brenton": "And in that day God shall shine gloriously in counsel on the earth, to exalt and glorify the remnant of Israel."}}, {"v": 3, "ref": "4:3", "o": "וְ/הָיָ֣ה הַ/נִּשְׁאָ֣ר בְּ/צִיּ֗וֹן וְ/הַ/נּוֹתָר֙ בִּ/יר֣וּשָׁלִַ֔ם קָד֖וֹשׁ יֵאָ֣מֶר ל֑/וֹ כָּל הַ/כָּת֥וּב לַ/חַיִּ֖ים בִּ/ירוּשָׁלִָֽם", "en": {"kjv": "And it shall come to pass, that he that is left in Zion, and he that remaineth in Jerusalem, shall be called holy, even every one that is written among the living in Jerusalem:", "web": "It will happen, that he who is left in Zion, and he who remains in Jerusalem, shall be called holy, even everyone who is written among the living in Jerusalem;", "bsb": "Whoever remains in Zion and whoever is left in Jerusalem will be called holy— all in Jerusalem who are recorded among the living—", "asv": "And it shall come to pass, that he that is left in Zion, and he that remaineth in Jerusalem, shall be called holy, even every one that is written among the living in Jerusalem;", "ylt": "And it hath been, he who is left in Zion, And he who is remaining in Jerusalem, `Holy' is said of him, Of every one who is written for life in Jerusalem.", "dra": "And it shall come to pass, that every one that shall be left in Sion, and that shall remain in Jerusalem, shall be called holy, every one that is written in life in Jerusalem.", "bbe": "And it will come about that the rest of the living in Zion, and of those who have been kept from destruction in Jerusalem, will be named holy, even everyone who has been recorded for life in Jerusalem:", "geneva": "Then hee that shalbe left in Zion, and hee that shall remaine in Ierusalem, shalbe called holy, and euery one shalbe written among the liuing in Ierusalem,", "wycliffe": "And it schal be, ech that is left in Sion, and is resydue in Jerusalem, schal be clepid hooli; ech that is writun in lijf in Jerusalem;", "rotherham": "And it shall come to pass—He that is left in Zion! And he that remaineth in Jerusalem, Shall be called, holy,—Everyone written unto life in Jerusalem.", "darby": "And it shall come to pass that he who remaineth in Zion, and he that is left in Jerusalem, shall be called holy, — every one that is written among the living in Jerusalem;", "twenty": "", "jps": "And it shall come to pass, that he that is left in Zion, and he that remaineth in Jerusalem, shall be called holy, even every one that is written unto life in Jerusalem;", "acv": "And it shall come to pass, that he who is left in Zion, and he who remains in Jerusalem, shall be called holy, even everyone who is written among the living in Jerusalem,", "anderson": "", "haweis": "", "noyes": "All that remain in Zion, And all that are left in Jerusalem, Shall be called holy; Every one that is written down for life in Jerusalem.", "webster": "And it shall come to pass, [that he that is] left in Zion, and [he that] remaineth in Jerusalem, shall be called holy, [even] every one that is written among the living in Jerusalem:", "vulgate": "et erit omnis qui relictus fuerit in Sion et residuus in Hierusalem sanctus vocabitur omnis qui scriptus est in vita in Hierusalem;", "brenton": "And it shall be, that the remnant left in Sion, and the remnant left in Jerusalem, even all that are appointed to life in Jerusalem, shall be called holy."}}, {"v": 4, "ref": "4:4", "o": "אִ֣ם רָחַ֣ץ אֲדֹנָ֗/י אֵ֚ת צֹאַ֣ת בְּנוֹת צִיּ֔וֹן וְ/אֶת דְּמֵ֥י יְרוּשָׁלִַ֖ם יָדִ֣יחַ מִ/קִּרְבָּ֑/הּ בְּ/ר֥וּחַ מִשְׁפָּ֖ט וּ/בְ/ר֥וּחַ בָּעֵֽר", "en": {"kjv": "When the Lord shall have washed away the filth of the daughters of Zion, and shall have purged the blood of Jerusalem from the midst thereof by the spirit of judgment, and by the spirit of burning.", "web": "when the Lord shall have washed away the filth of the daughters of Zion, and shall have purged the blood of Jerusalem from its midst, by the spirit of justice, and by the spirit of burning.", "bsb": "when the Lord has washed away the filth of the daughters of Zion and cleansed the bloodstains from the heart of Jerusalem by a spirit of judgment and a spirit of fire.", "asv": "when the Lord shall have washed away the filth of the daughters of Zion, and shall have purged the blood of Jerusalem from the midst thereof, by the spirit of justice, and by the spirit of burning.", "ylt": "If the Lord hath washed away The filth of daughters of Zion, And the blood of Jerusalem purgeth from her midst, By the spirit of judgment, and by the spirit of burning.", "dra": "If the Lord shall wash away the filth of the daughters of Sion, and shall wash away the blood of Jerusalem out of the midst thereof, by the spirit of judgment, and by the spirit of burning.", "bbe": "When Zion has been washed from her sin by the Lord, and Jerusalem made clean from her blood by a judging and a burning wind.", "geneva": "When the Lord shall wash the filthines of the daughters of Zion, and purge the blood of Ierusalem out of the middes thereof by the spirite of iudgement, and by the spirit of burning.", "wycliffe": "if the Lord waischith awei the filthis of the douytris of Sion, and waischith the blood of Jerusalem fro the myddis therof, in the spirit of doom, and in the spirit of heete.", "rotherham": "When My Lord shall have bathed away the filth of the daughters of Zion, And the blood-guiltiness of Jerusalem, he shall wash away out of her midst,—By the spirit of judgment, and By the spirit of thorough cleansing,", "darby": "when the Lord shall have washed away the filth of the daughters of Zion, and shall have scoured out the blood of Jerusalem from its midst, by the spirit of judgment, and by the spirit of burning.", "twenty": "", "jps": "when the L-rd shall have washed away the filth of the daughters of Zion, and shall have purged the blood of Jerusalem from the midst thereof, by the spirit of judgment, and by the spirit of destruction.", "acv": "when the Lord shall have washed away the filth of the daughters of Zion, and shall have purged the blood of Jerusalem from the midst of it, by the spirit of justice, and by the spirit of burning.", "anderson": "", "haweis": "", "noyes": "When the Lord shall have washed away the filth of the daughters of Zion, And have removed the blood of Jerusalem from the midst of her, By a spirit of judgment and a spirit of destruction,", "webster": "When the Lord shall have washed away the filth of the daughters of Zion, and shall have purged the blood of Jerusalem from the midst of it by the spirit of judgment, and by the spirit of burning.", "vulgate": "si abluerit Dominus sordem filiarum Sion et sanguinem Hierusalem laverit de medio eius spiritu iudicii et spiritu ardoris;", "brenton": "For the Lord shall wash away the filth of the sons and daughters of Sion, and shall purge out the blood from the midst of them, with the spirit of judgment, and the spirit of burning."}}, {"v": 5, "ref": "4:5", "o": "וּ/בָרָ֣א יְהוָ֡ה עַל֩ כָּל מְכ֨וֹן הַר צִיּ֜וֹן וְ/עַל מִקְרָאֶ֗/הָ עָנָ֤ן יוֹמָם֙ וְ/עָשָׁ֔ן וְ/נֹ֛גַהּ אֵ֥שׁ לֶהָבָ֖ה לָ֑יְלָה כִּ֥י עַל כָּל כָּב֖וֹד חֻפָּֽה", "en": {"kjv": "And the Lord will create upon every dwelling place of mount Zion, and upon her assemblies, a cloud and smoke by day, and the shining of a flaming fire by night: for upon all the glory shall be a defence.", "web": "Yahweh will create over the whole habitation of Mount Zion, and over her assemblies, a cloud and smoke by day, and the shining of a flaming fire by night; for over all the glory will be a canopy.", "bsb": "Then the LORD will create over all of Mount Zion and over her assemblies a cloud of smoke by day and a glowing flame of fire by night. For over all the glory there will be a canopy,", "asv": "And Jehovah will create over the whole habitation of mount Zion, and over her assemblies, a cloud and smoke by day, and the shining of a flaming fire by night; for over all the glory shall be spread a covering.", "ylt": "Then hath Jehovah prepared Over every fixed place of Mount Zion, And over her convocations, A cloud by day, and smoke, And the shining of a flaming fire by night, That, over all honour a safe-guard,", "dra": "And the Lord will create upon every place of mount Sion, and where he is called upon, a cloud by day, and a smoke and the brightness of a flaming fire in the night: for over all the glory shall be a protection.", "bbe": "And over every living-place on Mount Zion, all over all her meetings, the Lord will make a cloud and smoke by day, and the shining of a flaming fire by night, for over all, the glory of the Lord will be a cover and a tent;", "geneva": "And the Lord shall create vpon euery place of mount Zion, and vpon the assemblies thereof, a cloude and smoke by day, and the shining of a flaming fire by night: for vpon all the glory shall be a defence.", "wycliffe": "And the Lord made on ech place of the hille of Sion, and where he was clepid to help, a cloude bi dai, and smoke, and briytnesse of fier flawmynge in the niyt; for whi hilyng schal be aboue al glorie.", "rotherham": "Then will Yahweh, create—Over all the home of Mount Zion and Over her assembly, A cloud by day and a smoke, And the shining of a fire-flame, by night,—For over all the glory, shall be a canopy;", "darby": "And Jehovah will create over every dwelling-place of mount Zion, and over its convocations, a cloud by day and a smoke, and the brightness of a flame of fire by night: for over all the glory shall be a covering.", "twenty": "", "jps": "And HaShem will create over the whole habitation of mount Zion, and over her assemblies, a cloud and smoke by day, and the shining of a flaming fire by night; for over all the glory shall be a canopy.", "acv": "And Jehovah will create over the whole habitation of mount Zion, and over her assemblies, a cloud and smoke by day, and the shining of a flaming fire by night, for over all the glory, a covering.", "anderson": "", "haweis": "", "noyes": "Then shall Jehovah create upon the whole extent of mount Zion, and upon her places of assembly, A cloud and smoke by day, And the brightness of a flaming fire by night; Yea, for all that is glorious there shall be a shelter;", "webster": "And the LORD will create upon every dwelling place of mount Zion, and upon her assemblies, a cloud and smoke by day, and the shining of a flaming fire by night: for upon all the glory [shall be] a defense.", "vulgate": "et creabit Dominus super omnem locum montis Sion et ubi invocatus est nubem per diem et fumum et splendorem ignis flammantis in nocte super omnem enim gloriam protectio;", "brenton": "And he shall come, and it shall be with regard to every place of mount Sion, yea, all the region round about it shall a cloud overshadow by day, and there shall be as it were the smoke and light of fire burning by night: and upon all the glory shall be a defence."}}, {"v": 6, "ref": "4:6", "o": "וְ/סֻכָּ֛ה תִּהְיֶ֥ה לְ/צֵל יוֹמָ֖ם מֵ/חֹ֑רֶב וּ/לְ/מַחְסֶה֙ וּ/לְ/מִסְתּ֔וֹר מִ/זֶּ֖רֶם וּ/מִ/מָּטָֽר", "en": {"kjv": "And there shall be a tabernacle for a shadow in the daytime from the heat, and for a place of refuge, and for a covert from storm and from rain.", "web": "There will be a pavilion for a shade in the daytime from the heat, and for a refuge and for a shelter from storm and from rain.", "bsb": "a shelter to give shade from the heat by day, and a refuge and hiding place from the storm and the rain.", "asv": "And there shall be a pavilion for a shade in the day-time from the heat, and for a refuge and for a covert from storm and from rain.", "ylt": "And a covering may be, For a shadow by day from drought, And for a refuge, and for a hiding place, From inundation and from rain!", "dra": "And there shall be a tabernacle for a shade in the daytime from the heat, and for a security and covert from the whirlwind, and from rain.", "bbe": "And a shade in the daytime from the heat, and a safe cover from storm and from rain.", "geneva": "And a couering shalbe for a shadow in the day for the heate, and a place of refuge and a couert for the storme and for the raine.", "wycliffe": "And a tabernacle schal be in to a schadewynge place of the dai, fro heete, and in to sikirnesse and in to hidyng, fro whirlewynd and fro reyn.", "rotherham": "And a pavilion, shall there be For a shade by day, from the heat,—and For a refuge and for a shelter, from storm and from rain.", "darby": "And there shall be a tabernacle for shade by day from the heat, and for a shelter and for a covert from storm and from rain.", "twenty": "", "jps": "And there shall be a pavilion for a shadow in the day-time from the heat, and for a refuge and for a covert from storm and from rain.", "acv": "And there shall be a pavilion for a shade in the daytime from the heat, and for a refuge, and for a covert from storm and from rain.", "anderson": "", "haweis": "", "noyes": "There shall be a tent by day for a shadow from the heat, And for a refuge and shelter from the storm and rain.", "webster": "And there shall be a tabernacle for a shade in the day time from the heat, and for a place of refuge, and for a covert from storm and from rain.", "vulgate": "et tabernaculum erit in umbraculum diei ab aestu et in securitatem et absconsionem a turbine et a pluvia;", "brenton": "And it shall be for a shadow from the heat, and as a shelter and a hiding place from inclemency of weather and from rain."}}]}, {"c": 5, "verses": [{"v": 1, "ref": "5:1", "o": "אָשִׁ֤ירָה נָּא֙ לִֽ/ידִידִ֔/י שִׁירַ֥ת דּוֹדִ֖/י לְ/כַרְמ֑/וֹ כֶּ֛רֶם הָיָ֥ה לִֽ/ידִידִ֖/י בְּ/קֶ֥רֶן בֶּן שָֽׁמֶן", "en": {"kjv": "Now will I sing to my wellbeloved a song of my beloved touching his vineyard. My wellbeloved hath a vineyard in a very fruitful hill:", "web": "Let me sing for my well beloved a song of my beloved about his vineyard. My beloved had a vineyard on a very fruitful hill.", "bsb": "I will sing for my beloved a song of his vineyard: My beloved had a vineyard on a very fertile hill.", "asv": "Let me sing for my wellbeloved a song of my beloved touching his vineyard. My wellbeloved had a vineyard in a very fruitful hill:", "ylt": "Let me sing, I pray you, for my beloved, A song of my beloved as to his vineyard: My beloved hath a vineyard in a fruitful hill,", "dra": "I will sing to my beloved the canticle of my cousin concerning his vineyard. My beloved had a vineyard on a hill in a fruitful place.", "bbe": "Let me make a song about my loved one, a song of love for his vine-garden. My loved one had a vine-garden on a fertile hill:", "geneva": "Now will I sing to my beloued a song of my beloued to his vineyarde, My beloued had a vineyarde in a very fruitefull hill,", "wycliffe": "I schal synge for my derlyng the song of myn vnclis sone, of his vyner. A vyner was maad to my derlyng, in the horne in the sone of oile.", "rotherham": "Let me sing, I pray you, for a well-beloved of mine, The song of my beloved concerning his vineyard:—A vineyard, had my well-beloved on a very fruitful hill;", "darby": "I will sing to my well-beloved a song of my beloved touching his vineyard: My well-beloved had a vineyard upon a fruitful hill.", "twenty": "", "jps": "Let me sing of my well-beloved, a song of my beloved touching his vineyard. my well-beloved had a vineyard in a very fruitful hill;", "acv": "Let me sing for my well-beloved a song of my beloved concerning his vineyard. My well-beloved had a vineyard in a very fruitful hill.", "anderson": "", "haweis": "", "noyes": "Let me sing now a song respecting my friend, A song respecting my friend touching his vineyard. My friend had a vineyard On a very fruitful hill;", "webster": "Now will I sing to my well-beloved a song of my beloved concerning his vineyard. My well-beloved hath a vineyard in a very fruitful hill:", "vulgate": "cantabo dilecto meo canticum patruelis mei vineae suae vinea facta est dilecto meo in cornu filio olei;", "brenton": "Now I will sing to my beloved a song of my beloved concerning my vineyard. My beloved had a vineyard on a high hill in a fertile place."}}, {"v": 2, "ref": "5:2", "o": "וַֽ/יְעַזְּקֵ֣/הוּ וַֽ/יְסַקְּלֵ֗/הוּ וַ/יִּטָּעֵ֨/הוּ֙ שֹׂרֵ֔ק וַ/יִּ֤בֶן מִגְדָּל֙ בְּ/תוֹכ֔/וֹ וְ/גַם יֶ֖קֶב חָצֵ֣ב בּ֑/וֹ וַ/יְקַ֛ו לַ/עֲשׂ֥וֹת עֲנָבִ֖ים וַ/יַּ֥עַשׂ בְּאֻשִֽׁים", "en": {"kjv": "And he fenced it, and gathered out the stones thereof, and planted it with the choicest vine, and built a tower in the midst of it, and also made a winepress therein: and he looked that it should bring forth grapes, and it brought forth wild grapes.", "web": "He dug it up, gathered out its stones, planted it with the choicest vine, built a tower in its midst, and also cut out a wine press therein. He looked for it to yield grapes, but it yielded wild grapes.", "bsb": "He dug it up and cleared the stones and planted the finest vines. He built a watchtower in the middle and dug out a winepress as well. He waited for the vineyard to yield good grapes, but the fruit it produced was sour!", "asv": "and he digged it, and gathered out the stones thereof, and planted it with the choicest vine, and built a tower in the midst of it, and also hewed out a winepress therein: and he looked that it should bring forth grapes, and it brought forth wild grapes.", "ylt": "And he fenceth it, and casteth out its stones, And planteth it with a choice vine, And buildeth a tower in its midst, And also a wine press hath hewn out in it, And he waiteth for the yielding of grapes, And it yieldeth bad ones!", "dra": "And he fenced it in, and picked the stones out of it, and planted it with the choicest vines, and built a tower in the midst thereof, and set up a winepress therein: and he looked that it should bring forth grapes, and it brought forth wild grapes.", "bbe": "And after working the earth of it with a spade, he took away its stones, and put in it a very special vine; and he put up a watchtower in the middle of it, hollowing out in the rock a place for the grape-crushing; and he was hoping that it would give the best grapes, but it gave common grapes.", "geneva": "And hee hedged it, and gathered out the stones of it, and he planted it with the best plants, and hee builte a towre in the middes thereof, and made a wine presse therein: then hee looked that it should bring foorth grapes: but it brought foorth wilde grapes.", "wycliffe": "And he heggide it, and chees stoonys therof, and plauntide a chosun vyner; and he bildide a tour in the myddis therof, and rerede a presse ther ynne; and he abood, that it schulde bere grapis, and it bare wielde grapis.", "rotherham": "And he thoroughly digged it, And gathered out the stones thereof, And planted it with a precious vine, And built a tower in the midst thereof, Moreover also a wine-press, hewed he therein,—Then waited he that it should bring forth grapes. And it brought forth wild grapes:", "darby": "And he dug it, and gathered out the stones thereof, and planted it with the choicest vine; and he built a tower in the midst of it, and also hewed out a winepress therein; and he looked that it should bring forth grapes, but it brought forth wild grapes.", "twenty": "", "jps": "And he digged it, and cleared it of stones, and planted it with the choicest vine, and built a tower in the midst of it, and also hewed out a vat therein; and he looked that it should bring forth grapes, and it brought forth wild grapes.", "acv": "And he dug it, and gathered out the stones of it, and planted it with the choicest vine, and built a tower in the midst of it, and also hewed out a winepress in it. And he looked that it should bring forth grapes, and it brought forth wild grapes.", "anderson": "", "haweis": "", "noyes": "He digged it, and cleared it of stones, And planted it with the choicest vine, And built a tower in the midst of it, And hewed out a wine-press therein; Then he looked that it should bring forth its grapes, But it brought forth sour grapes.", "webster": "And he fenced it, and gathered out the stones of it, and planted it with the choicest vine, and built a tower in the midst of it, and also made a wine-press therein: and he expected that it would bring forth grapes, and it brought forth wild grapes.", "vulgate": "et sepivit eam et lapides elegit ex illa et plantavit eam electam et aedificavit turrem in medio eius et torcular extruxit in ea et expectavit ut faceret uvas et fecit labruscas;", "brenton": "And I made a hedge round it, and dug a trench, and planted a choice vine, and built a tower in the midst of it, and dug a place for the wine-vat in it: and I waited for it to bring forth grapes, and it brought forth thorns."}}, {"v": 3, "ref": "5:3", "o": "וְ/עַתָּ֛ה יוֹשֵׁ֥ב יְרוּשָׁלִַ֖ם וְ/אִ֣ישׁ יְהוּדָ֑ה שִׁפְטוּ נָ֕א בֵּינִ֖/י וּ/בֵ֥ין כַּרְמִֽ/י", "en": {"kjv": "And now, O inhabitants of Jerusalem, and men of Judah, judge, I pray you, betwixt me and my vineyard.", "web": "“Now, inhabitants of Jerusalem and men of Judah, please judge between me and my vineyard.", "bsb": "“And now, O dwellers of Jerusalem and men of Judah, I exhort you to judge between Me and My vineyard.", "asv": "And now, O inhabitants of Jerusalem and men of Judah, judge, I pray you, betwixt me and my vineyard.", "ylt": "And now, O inhabitant of Jerusalem, and man of Judah, Judge, I pray you, between me and my vineyard.", "dra": "And now, O ye inhabitants of Jerusalem, and ye men of Juda, judge between me and my vineyard.", "bbe": "And now, you people of Jerusalem and you men of Judah, be the judges between me and my vine-garden.", "geneva": "Now therefore, O inhabitants of Ierusalem and men of Iudah, iudge, I pray you, betweene me, and my vineyarde.", "wycliffe": "Now therfor, ye dwelleris of Jerusalem, and ye men of Juda, deme bitwixe me and my viner.", "rotherham": "Now, therefore, O inhabitant of Jerusalem, And men of Judah,—Judge, I pray you, betwixt me, and my vineyard:—", "darby": "And now, inhabitants of Jerusalem and men of Judah, judge, I pray you, between me and my vineyard.", "twenty": "", "jps": "And now, O inhabitants of Jerusalem and men of Judah, judge, I pray you, betwixt me and my vineyard.", "acv": "And now, O inhabitants of Jerusalem and men of Judah, judge, I pray you, between me and my vineyard.", "anderson": "", "haweis": "", "noyes": "And now, O inhabitants of Jerusalem, and men of Judah, Judge ye between me and my vineyard!", "webster": "And now, O inhabitants of Jerusalem, and men of Judah, judge, I pray you, betwixt me and my vineyard.", "vulgate": "nunc ergo habitator Hierusalem et vir Iuda iudicate inter me et inter vineam meam;", "brenton": "And now, ye dwellers in Jerusalem, and every man of Juda, judge between me and my vineyard."}}, {"v": 4, "ref": "5:4", "o": "מַה לַּ/עֲשׂ֥וֹת עוֹד֙ לְ/כַרְמִ֔/י וְ/לֹ֥א עָשִׂ֖יתִי בּ֑/וֹ מַדּ֧וּעַ קִוֵּ֛יתִי לַ/עֲשׂ֥וֹת עֲנָבִ֖ים וַ/יַּ֥עַשׂ בְּאֻשִֽׁים", "en": {"kjv": "What could have been done more to my vineyard, that I have not done in it? wherefore, when I looked that it should bring forth grapes, brought it forth wild grapes?", "web": "What could have been done more to my vineyard, that I have not done in it? Why, when I looked for it to yield grapes, did it yield wild grapes?", "bsb": "What more could I have done for My vineyard than I already did for it? Why, when I expected sweet grapes, did it bring forth sour fruit?", "asv": "What could have been done more to my vineyard, that I have not done in it? wherefore, when I looked that it should bring forth grapes, brought it forth wild grapes?", "ylt": "What--to do still to my vineyard, That I have not done in it! Wherefore, I waited to the yielding of grapes, And it yieldeth bad ones!", "dra": "What is there that I ought to do more to my vineyard, that I have not done to it? was it that I looked that it should bring forth grapes, and it hath brought forth wild grapes?", "bbe": "Is there anything which might have been done for my vine-garden which I have not done? why then, when I was hoping for the best grapes did it give me common grapes?", "geneva": "What coulde I haue done any more to my vineyard that I haue not done vnto it? why haue I looked that it should bring foorth grapes, and it bringeth foorth wilde grapes?", "wycliffe": "What is it that Y ouyt to do more to my vyner, and Y dide not to it? whether that Y abood, that it schulde bere grapis, and it bare wielde grapis?", "rotherham": "What could have been done further to my vineyard, That I had not done in it? Why then—When I had waited that it should bring forth grapes, Brought it forth, wild grapes?", "darby": "What was there yet to do to my vineyard that I have not done in it? Wherefore, when I looked that it should bring forth grapes, brought it forth wild grapes? —", "twenty": "", "jps": "What could have been done more to my vineyard, that I have not done in it? Wherefore, when I looked that it should bring forth grapes, brought it forth wild grapes?", "acv": "What could have been done more to my vineyard that I have not done in it? Why, when I looked that it should bring forth grapes, it brought forth wild grapes?", "anderson": "", "haweis": "", "noyes": "What could have been done for my vineyard That I have not done for it? Why, then, when I looked that it should bring forth its grapes, Brought it forth sour grapes?", "webster": "What more could have been done to my vineyard, that I have not done in it? Why, when I expected that it would bring forth grapes, brought it forth wild grapes?", "vulgate": "quid est quod debui ultra facere vineae meae et non feci ei an quod expectavi ut faceret uvas et fecit labruscas;", "brenton": "What shall I do any more to my vineyard, that I have not done to it? Whereas I expected it to bring forth grapes, but it has brought forth thorns."}}, {"v": 5, "ref": "5:5", "o": "וְ/עַתָּה֙ אוֹדִֽיעָה נָּ֣א אֶתְ/כֶ֔ם אֵ֛ת אֲשֶׁר אֲנִ֥י עֹשֶׂ֖ה לְ/כַרְמִ֑/י הָסֵ֤ר מְשׂוּכָּת/וֹ֙ וְ/הָיָ֣ה לְ/בָעֵ֔ר פָּרֹ֥ץ גְּדֵר֖/וֹ וְ/הָיָ֥ה לְ/מִרְמָֽס", "en": {"kjv": "And now go to; I will tell you what I will do to my vineyard: I will take away the hedge thereof, and it shall be eaten up; and break down the wall thereof, and it shall be trodden down:", "web": "Now I will tell you what I will do to my vineyard. I will take away its hedge, and it will be eaten up. I will break down its wall of it, and it will be trampled down.", "bsb": "Now I will tell you what I am about to do to My vineyard: I will take away its hedge, and it will be consumed; I will tear down its wall, and it will be trampled.", "asv": "And now I will tell you what I will do to my vineyard: I will take away the hedge thereof, and it shall be eaten up; I will break down the wall thereof, and it shall be trodden down:", "ylt": "And now, pray, let me cause you to know, That which I am doing to my vineyard, To turn aside its hedge, And it hath been for consumption, To break down its wall, And it hath been for a treading-place.", "dra": "And now I will shew you what I will do to my vineyard. I will take away the hedge thereof, and it shall be wasted: I will break down the wall thereof, and it shall be trodden down.", "bbe": "And now, this is what I will do to my vine-garden: I will take away the circle of thorns round it, and it will be burned up; its wall will be broken down and the beasts of the field will go through it;", "geneva": "And nowe I will tell you what I will do to my vineyarde: I will take away the hedge thereof, and it shall be eaten vp: I will breake the wall thereof, and it shall be troden downe:", "wycliffe": "And now Y schal schewe to you, what Y schal do to my vyner. Y schal take awei the hegge therof, and it schal be in to rauyschyng; Y schal caste doun the wal therof, and it schal be in to defoulyng; and Y schal sette it desert,", "rotherham": "Now, therefore, I pray you, let me tell, you, what I am about to do to my vineyard,—To take away the fence thereof And it shall be eaten up, To destroy the wall thereof And it shall be trodden down;", "darby": "And now, let me tell you what I am about to do to my vineyard: I will take away its hedge, and it shall be eaten up; I will break down its wall, and it shall be trodden under foot;", "twenty": "", "jps": "And now come, I will tell you what I will do to my vineyard: I will take away the hedge thereof, and it shall be eaten up; I will break down the fence thereof, and it shall be trodden down;", "acv": "And now I will tell you what I will do to my vineyard. I will take away the hedge of it, and it shall be eaten up. I will break down the wall of it, and it shall be trodden down.", "anderson": "", "haweis": "", "noyes": "But come now, and I will tell you What I mean to do with my vineyard. I will take away its hedge, and it shall be eaten up; I will break down its wall, and it shall be trodden down!", "webster": "And now come; I will tell you what I will do to my vineyard: I will take away its hedge, and it shall be eaten up; [and] break down the wall of it, and it shall be trodden down:", "vulgate": "et nunc ostendam vobis quid ego faciam vineae meae auferam sepem eius et erit in direptionem diruam maceriam eius et erit in conculcationem;", "brenton": "And now I will tell you what I will do to my vineyard: I will take away its hedge, and it shall be for a spoil; and I will pull down its walls, and it shall be left to be trodden down."}}, {"v": 6, "ref": "5:6", "o": "וַ/אֲשִׁיתֵ֣/הוּ בָתָ֗ה לֹ֤א יִזָּמֵר֙ וְ/לֹ֣א יֵעָדֵ֔ר וְ/עָלָ֥ה שָׁמִ֖יר וָ/שָׁ֑יִת וְ/עַ֤ל הֶ/עָבִים֙ אֲצַוֶּ֔ה מֵ/הַמְטִ֥יר עָלָ֖י/ו מָטָֽר", "en": {"kjv": "And I will lay it waste: it shall not be pruned, nor digged; but there shall come up briers and thorns: I will also command the clouds that they rain no rain upon it.", "web": "I will lay it a wasteland. It won’t be pruned nor hoed, but it will grow briers and thorns. I will also command the clouds that they rain no rain on it.”", "bsb": "I will make it a wasteland, neither pruned nor cultivated, and thorns and briers will grow up. I will command the clouds that rain shall not fall on it.”", "asv": "and I will lay it waste; it shall not be pruned nor hoed; but there shall come up briers and thorns: I will also command the clouds that they rain no rain upon it.", "ylt": "And I make it a waste, It is not pruned, nor arranged, And gone up have brier and thorn, And on the thick clouds I lay a charge, From raining upon it rain.", "dra": "And I will make it desolate: it shall not be pruned, and it shall not be digged: but briers and thorns shall come up: and I will command the clouds to rain no rain upon it.", "bbe": "And I will make it waste; its branches will not be touched with the knife, or the earth worked with the spade; but blackberries and thorns will come up in it: and I will give orders to the clouds not to send rain on it.", "geneva": "And I will laye it waste: it shall not be cut, nor digged, but briers, and thornes shall growe vp: I will also commande the cloudes that they raine no raine vpon it.", "wycliffe": "ether forsakun. It schal not be kit, and it schal not be diggid, and breris and thornes schulen `growe vp on it; and Y schal comaunde to cloudis, that tho reyne not reyn on it.", "rotherham": "And I will make it a waste;—It shall be neither pruned nor hoed, But there shall come up briars and thorns,—And upon the clouds, will I lay a charge, That they rain thereon no rain.", "darby": "and I will make it a waste — it shall not be pruned nor cultivated, but there shall come up briars and thorns; and I will command the clouds that they rain no rain upon it.", "twenty": "", "jps": "And I will lay it waste: it shall not be pruned nor hoed, but there shall come up briers and thorns; I will also command the clouds that they rain no rain upon it.", "acv": "And I will lay it waste. It shall not be pruned nor hoed, but there shall come up briers and thorns. I will also command the clouds that they rain no rain upon it.", "anderson": "", "haweis": "", "noyes": "And I will make it a waste; It shall not be pruned, nor digged, But shall grow up into thorns and briers; I will also command the clouds That they shed no rain upon it.", "webster": "And I will lay it waste: it shall not be pruned, nor digged; but there shall come up briers and thorns: I will also command the clouds that they rain no rain upon it.", "vulgate": "et ponam eam desertam non putabitur et non fodietur et ascendent vepres et spinae et nubibus mandabo ne pluant super eam imbrem;", "brenton": "And I will forsake my vineyard; and it shall not be pruned, nor dug, and thorns shall come up upon it as on barren land; and I will command the clouds to rain no rain upon it."}}, {"v": 7, "ref": "5:7", "o": "כִּ֣י כֶ֜רֶם יְהוָ֤ה צְבָאוֹת֙ בֵּ֣ית יִשְׂרָאֵ֔ל וְ/אִ֣ישׁ יְהוּדָ֔ה נְטַ֖ע שַׁעֲשׁוּעָ֑י/ו וַ/יְקַ֤ו לְ/מִשְׁפָּט֙ וְ/הִנֵּ֣ה מִשְׂפָּ֔ח לִ/צְדָקָ֖ה וְ/הִנֵּ֥ה צְעָקָֽה", "en": {"kjv": "For the vineyard of the Lord of hosts is the house of Israel, and the men of Judah his pleasant plant: and he looked for judgment, but behold oppression; for righteousness, but behold a cry.", "web": "For the vineyard of Yahweh of Armies is the house of Israel, and the men of Judah his pleasant plant: and he looked for justice, but, behold, oppression; for righteousness, but, behold, a cry of distress.", "bsb": "For the vineyard of the LORD of Hosts is the house of Israel, and the men of Judah are the plant of His delight. He looked for justice, but saw bloodshed; for righteousness, but heard a cry of distress.", "asv": "For the vineyard of Jehovah of hosts is the house of Israel, and the men of Judah his pleasant plant: and he looked for justice, but, behold, oppression; for righteousness, but, behold, a cry.", "ylt": "Because the vineyard of Jehovah of Hosts Is the house of Israel, And the man of Judah His pleasant plant, And He waiteth for judgment, and lo, oppression, For righteousness, and lo, a cry.", "dra": "For the vineyard of the Lord of hosts is the house of Israel: and the man of Juda, his pleasant plant: and I looked that he should do judgment, and behold iniquity: and do justice, and behold a cry.", "bbe": "For the vine-garden of the Lord of armies is the people of Israel, and the men of Judah are the plant of his delight: and he was looking for upright judging, and there was blood; for righteousness, and there was a cry for help.", "geneva": "Surely the vineyard of the Lord of hostes is the house of Israel, and the men of Iudah are his pleasant plant, and hee looked for iudgement, but beholde oppression: for righteousnesse, but beholde a crying.", "wycliffe": "Forsothe the vyner of the Lord of oostis is the hous of Israel, and the men of Juda ben the delitable buriownyng of hym. Y abood, that it schal make doom, and lo! wickidnesse; and that it schulde do riytfulnesse, and lo! cry.", "rotherham": "Surely the vineyard of Yahweh of hosts, is the house of Israel, And, the men of Judah, are the plantation in which he dearly delighted,—And he waited, For equity but lo! murderous iniquity, For the rule of right but lo the cry of the wronged.", "darby": "For the vineyard of Jehovah of hosts is the house of Israel, and the men of Judah the plant of his delight: and he looked for justice, and behold, blood-shedding; for righteousness, and behold, a cry.", "twenty": "", "jps": "For the vineyard of HaShem of hosts is the house of Israel, and the men of Judah the plant of His delight; and He looked for justice, but behold violence; for righteousness, but behold a cry.", "acv": "For the vineyard of Jehovah of hosts is the house of Israel, and the men of Judah his pleasant plant. And he looked for justice, but behold, oppression, for righteousness, but behold, a cry.", "anderson": "", "haweis": "", "noyes": "The vineyard of Jehovah of hosts is the house of Israel, And the men of Judah the plant of his delight. He looked for justice, and behold, bloodshed! For righteousness, and behold, outcry!", "webster": "For the vineyard of the LORD of hosts [is] the house of Israel, and the men of Judah his pleasant plant: and he looked for judgment, but behold oppression; for righteousness, but behold a cry.", "vulgate": "vinea enim Domini exercituum domus Israhel et vir Iuda germen delectabile eius et expectavi ut faceret iudicium et ecce iniquitas et iustitiam et ecce clamor;", "brenton": "For the vineyard of the Lord of hosts is the house of Israel, and the men of Juda his beloved plant: I expected it to bring forth judgment, and it brought forth iniquity; and not righteousness, but a cry."}}, {"v": 8, "ref": "5:8", "o": "ה֗וֹי מַגִּיעֵ֥י בַ֨יִת֙ בְּ/בַ֔יִת שָׂדֶ֥ה בְ/שָׂדֶ֖ה יַקְרִ֑יבוּ עַ֚ד אֶ֣פֶס מָק֔וֹם וְ/הֽוּשַׁבְתֶּ֥ם לְ/בַדְּ/כֶ֖ם בְּ/קֶ֥רֶב הָ/אָֽרֶץ", "en": {"kjv": "Woe unto them that join house to house, that lay field to field, till there be no place, that they may be placed alone in the midst of the earth!", "web": "Woe to those who join house to house, who lay field to field, until there is no room, and you are made to dwell alone in the midst of the land!", "bsb": "Woe to you who add house to house and join field to field until no place is left and you live alone in the land.", "asv": "Woe unto them that join house to house, that lay field to field, till there be no room, and ye be made to dwell alone in the midst of the land!", "ylt": "Woe to those joining house to house, Field to field they bring near, till there is no place, And ye have been settled by yourselves In the midst of the land!", "dra": "Woe to you that join house to house and lay field to field, even to the end of the place: shall you alone dwell in the midst of the earth?", "bbe": "Cursed are those who are joining house to house, and putting field to field, till there is no more living-space for any but themselves in all the land!", "geneva": "Woe vnto them that ioyne house to house, and laye fielde to fielde, till there bee no place, that ye may be placed by your selues in the mids of the earth.", "wycliffe": "Wo to you that ioynen hows to hous, and couplen feeld to feeld, `til to the ende of place. Whether ye aloone schulen dwelle in the myddis of the lond?", "rotherham": "Alas for them who join house to house, Field to field, bring they near,—Until there is no room, But ye are left to dwell alone in the midst of the land.", "darby": "Woe unto them that add house to house, that join field to field, until there is no more room, and that ye dwell yourselves alone in the midst of the land!", "twenty": "", "jps": "Woe unto them that join house to house, that lay field to field, till there be no room, and ye be made to dwell alone in the midst of the land!", "acv": "Woe to those who join house to house, who lay field to field, till there is no room, and ye be made to dwell alone in the midst of the land!", "anderson": "", "haweis": "", "noyes": "Woe to them that join house to house, That add field to field, Till there is no place left, And they dwell alone in the land.", "webster": "Woe to them that join house to house, [that] lay field to field, till [there is] no place, that they may be placed alone in the midst of the earth!", "vulgate": "vae qui coniungitis domum ad domum et agrum agro copulatis usque ad terminum loci numquid habitabitis soli vos in medio terrae;", "brenton": "Woe to them that join house to house, and add field to field, that they may take away something of their neighbor's: will ye dwell alone upon the land?"}}, {"v": 9, "ref": "5:9", "o": "בְּ/אָזְנָ֖/י יְהוָ֣ה צְבָא֑וֹת אִם לֹ֞א בָּתִּ֤ים רַבִּים֙ לְ/שַׁמָּ֣ה יִֽהְי֔וּ גְּדֹלִ֥ים וְ/טוֹבִ֖ים מֵ/אֵ֥ין יוֹשֵֽׁב", "en": {"kjv": "In mine ears said the Lord of hosts, Of a truth many houses shall be desolate, even great and fair, without inhabitant.", "web": "In my ears, Yahweh of Armies says: “Surely many houses will be desolate, even great and beautiful, unoccupied.", "bsb": "I heard the LORD of Hosts declare: “Surely many houses will become desolate, great mansions left unoccupied.", "asv": "In mine ears saith Jehovah of hosts, Of a truth many houses shall be desolate, even great and fair, without inhabitant.", "ylt": "By the weapons of Jehovah of Hosts Do not many houses a desolation become? Great and good without inhabitant!", "dra": "These things are in my ears, saith the Lord of hosts: Unless many great and fair houses shall become desolate, without an inhabitant.", "bbe": "The Lord of armies has said to me secretly, Truly, numbers of great and fair houses will be waste, with no one living in them.", "geneva": "This is in mine cares, saith the Lord of hostes. Surely many houses shall be desolate, euen great, and faire without inhabitant.", "wycliffe": "These thingis ben in the eeris of me, the Lord of oostis; if many housis ben not forsakun, grete housis and faire, with outen dwellere, bileue ye not to me.", "rotherham": "In mine ears, [said] Yahweh of hosts,—Verily, houses in abundance, shall become, a desolation, Large and fair, without inhabitant;", "darby": "In mine ears Jehovah of hosts [hath said], Many houses shall assuredly become a desolation, great and excellent ones, without inhabitant.", "twenty": "", "jps": "In mine ears said HaShem of hosts: of a truth many houses shall be desolate, even great and fair, without inhabitant.", "acv": "In my ears says Jehovah of hosts, of a truth many houses shall be desolate, even great and fair, without inhabitant.", "anderson": "", "haweis": "", "noyes": "To mine ear hath Jehovah of hosts revealed it: Surely many houses shall become a desolation, The great and the fair ones, without an inhabitant.", "webster": "In my ears [said] the LORD of hosts, Of a truth many houses shall be desolate, [even] great and fair, without inhabitant.", "vulgate": "in auribus meis sunt haec Domini exercituum nisi domus multae desertae fuerint grandes et pulchrae absque habitatore;", "brenton": "For these things have reached the ears of the Lord of hosts: for though many houses should be built, many and fair houses shall be desolate, and there shall be no inhabitants in them."}}, {"v": 10, "ref": "5:10", "o": "כִּ֗י עֲשֶׂ֨רֶת֙ צִמְדֵּי כֶ֔רֶם יַעֲשׂ֖וּ בַּ֣ת אֶחָ֑ת וְ/זֶ֥רַע חֹ֖מֶר יַעֲשֶׂ֥ה אֵיפָֽה", "en": {"kjv": "Yea, ten acres of vineyard shall yield one bath, and the seed of an homer shall yield an ephah.", "web": "For ten acres of vineyard shall yield one bath, and a homer of seed shall yield an ephah.”", "bsb": "For ten acres of vineyard will yield but a bath of wine, and a homer of seed only an ephah of grain.”", "asv": "For ten acres of vineyard shall yield one bath, and a homer of seed shall yield but an ephah.", "ylt": "For ten acres of vineyard do yield one bath, And an homer of seed yieldeth an ephah.", "dra": "For ten acres of vineyard shall yield one little measure, and thirty bushels of seed shall yield three bushels.", "bbe": "For ten fields of vines will only give one measure of wine, and a great amount of seed will only give a small measure of grain.", "geneva": "For ten acres of vines shall yelde one bath, and the seede of an homer shall yelde an ephah.", "wycliffe": "For whi ten acris of vynes schulen make a potel, and thretti buschels of seed schulen make thre buschels.", "rotherham": "For, ten yokes of vineyard, shall yield one bath,—And the seed of a homer, shall yield an ephah,", "darby": "Yea, ten acres of vineyard shall yield one bath, and a homer of seed shall yield an ephah.", "twenty": "", "jps": "For ten acres of vineyard shall yield one bath, and the seed of a homer shall yield an ephah.", "acv": "For ten acres of vineyard shall yield one bath, and a homer of seed shall yield but an ephah.", "anderson": "", "haweis": "", "noyes": "Yea, ten acres of vineyard shall yield a single bath of wine, And a homer of seed shall produce but an ephah.", "webster": "Yes, ten acres of vineyard shall yield one bath, and the seed of a homer shall yield an ephah.", "vulgate": "decem enim iuga vinearum facient lagunculam unam et triginta modii sementis facient modios tres;", "brenton": "For where ten yoke of oxen plough the land shall yield one jar-full, and he that sows six homers shall produce three measures."}}, {"v": 11, "ref": "5:11", "o": "ה֛וֹי מַשְׁכִּימֵ֥י בַ/בֹּ֖קֶר שֵׁכָ֣ר יִרְדֹּ֑פוּ מְאַחֲרֵ֣י בַ/נֶּ֔שֶׁף יַ֖יִן יַדְלִיקֵֽ/ם", "en": {"kjv": "Woe unto them that rise up early in the morning, that they may follow strong drink; that continue until night, till wine inflame them!", "web": "Woe to those who rise up early in the morning, that they may follow strong drink; who stay late into the night, until wine inflames them!", "bsb": "Woe to those who rise early in the morning in pursuit of strong drink, who linger into the evening, to be inflamed by wine.", "asv": "Woe unto them that rise up early in the morning, that they may follow strong drink; that tarry late into the night, till wine inflame them!", "ylt": "Woe to those rising early in the morning, Strong drink they pursue! Tarrying in twilight, wine inflameth them!", "dra": "Woe to you that rise up early in the morning to follow drunkenness, and to drink in the evening, to be inflamed with wine.", "bbe": "Cursed are those who get up early in the morning to give themselves up to strong drink; who keep on drinking far into the night till they are heated with wine!", "geneva": "Wo vnto them, that rise vp early to follow drunkennes, and to them that continue vntill night, till the wine doe inflame them.", "wycliffe": "Wo to you that risen togidere eerli to sue drunkennesse, and to drinke `til to euentid, that ye brenne with wyn.", "rotherham": "Alas, for them who rise early in the morning that strong drink, they may pursue,—Who follow on in the evening cool [until] with wine, they are heated;", "darby": "Woe unto them that, rising early in the morning, run after strong drink; that linger till twilight, [till] wine inflameth them!", "twenty": "", "jps": "Woe unto them that rise up early in the morning, that they may follow strong drink; that tarry late into the night, till wine inflame them!", "acv": "Woe to those who rise up early in the morning, that they may follow strong drink, who tarry late into the night, till wine inflame them!", "anderson": "", "haweis": "", "noyes": "Woe to them that rise early in the morning to follow strong drink,—Who sit late in the night that wine may inflame them!", "webster": "Woe to them that rise early in the morning, [that] they may follow strong drink; that continue until night, [till] wine inflameth them!", "vulgate": "vae qui consurgitis mane ad ebrietatem sectandam et potandum usque ad vesperam ut vino aestuetis;", "brenton": "Woe to them that rise up in the morning, and follow strong drink; who wait at it till evening: for the wine shall inflame them."}}, {"v": 12, "ref": "5:12", "o": "וְ/הָיָ֨ה כִנּ֜וֹר וָ/נֶ֗בֶל תֹּ֧ף וְ/חָלִ֛יל וָ/יַ֖יִן מִשְׁתֵּי/הֶ֑ם וְ/אֵ֨ת פֹּ֤עַל יְהוָה֙ לֹ֣א יַבִּ֔יטוּ וּ/מַעֲשֵׂ֥ה יָדָ֖י/ו לֹ֥א רָאֽוּ", "en": {"kjv": "And the harp, and the viol, the tabret, and pipe, and wine, are in their feasts: but they regard not the work of the Lord, neither consider the operation of his hands.", "web": "The harp, lyre, tambourine, and flute, with wine, are at their feasts; but they don’t respect the work of Yahweh, neither have they considered the operation of his hands.", "bsb": "At their feasts are the lyre and harp, tambourines and flutes and wine. They disregard the actions of the LORD and fail to see the work of His hands.", "asv": "And the harp and the lute, the tabret and the pipe, and wine, are in their feasts; but they regard not the work of Jehovah, neither have they considered the operation of his hands.", "ylt": "And harp, and psaltery, tabret, and pipe, And wine, have been their banquets, And the work of Jehovah they behold not, Yea, the work of His hands they have not seen.", "dra": "The harp, and the lyre, and, the timbrel and the pipe, and wine are in your feasts: and the work of the Lord you regard not, nor do you consider the works of his hands.", "bbe": "And corded instruments and wind-instruments and wine are in their feasts: but they give no thought to the work of the Lord, and they are not interested in what his hands are doing.", "geneva": "And the harpe and viole, timbrel, and pipe, and wine are in their feastes: but they regard not the worke of the Lord, neither consider the worke of his handes.", "wycliffe": "Harpe, and giterne, and tympan, and pipe, and wyn ben in youre feestis; and ye biholden not the werk of the Lord, nether ye biholden the werkis of hise hondis.", "rotherham": "And it cometh to pass—that lyre and harp, timbrel and flute and wine are in their banquets,—But, the doing of Yahweh, they do not discern, And the work of his hands, have they not seen.", "darby": "And harp and lyre, tambour and flute, and wine are in their banquets; but they regard not the work of Jehovah, nor do they see the operation of his hands.", "twenty": "", "jps": "And the harp and the psaltery, the tabret and the pipe, and wine, are in their feasts; but they regard not the work of HaShem, neither have they considered the operation of His hands.", "acv": "And the harp and the lute, the tambourine and the pipe, and wine, are in their feasts, but they do not regard the work of Jehovah, nor have they considered the operation of his hands.", "anderson": "", "haweis": "", "noyes": "And the lyre and the harp, the tabret and the pipe, and wine, are at their feasts, But they regard not the work of Jehovah, Nor attend to the operation of his hands.", "webster": "And the harp, and the viol, the tabret, and pipe, and wine, are in their feasts: but they regard not the work of the LORD, neither consider the operation of his hands.", "vulgate": "cithara et lyra et tympanum et tibia et vinum in conviviis vestris et opus Domini non respicitis nec opera manuum eius consideratis;", "brenton": "For they drink wine with harp, and psaltery, and drums, and pipes: but they regard not the works of the Lord, and consider not the works of his hands."}}, {"v": 13, "ref": "5:13", "o": "לָ/כֵ֛ן גָּלָ֥ה עַמִּ֖/י מִ/בְּלִי דָ֑עַת וּ/כְבוֹד/וֹ֙ מְתֵ֣י רָעָ֔ב וַ/הֲמוֹנ֖/וֹ צִחֵ֥ה צָמָֽא", "en": {"kjv": "Therefore my people are gone into captivity, because they have no knowledge: and their honourable men are famished, and their multitude dried up with thirst.", "web": "Therefore my people go into captivity for lack of knowledge. Their honorable men are famished, and their multitudes are parched with thirst.", "bsb": "Therefore My people will go into exile for their lack of understanding; their dignitaries are starving and their masses are parched with thirst.", "asv": "Therefore my people are gone into captivity for lack of knowledge; and their honorable men are famished, and their multitude are parched with thirst.", "ylt": "Therefore my people removed without knowledge, And its honourable ones are famished, And its multitude dried up of thirst.", "dra": "Therefore is my people led away captive, because they had not knowledge, and their nobles have perished with famine, and their multitude were dried up with thirst.", "bbe": "For this cause my people are taken away as prisoners into strange countries for need of knowledge: and their rulers are wasted for need of food, and their loud-voiced feasters are dry for need of water.", "geneva": "Therefore my people is gone into captiuitie, because they had no knowledge, and the glorie thereof are men famished, and the multitude thereof is dried vp with thirst.", "wycliffe": "Therfor my puple is led prisoner, for it hadde not kunnyng; and the noble men therof perischiden in hungur, and the multitude therof was drye in thirst.", "rotherham": "Therefore, are my people taken away captive before they know it,—And their honourable men are famished with hunger, And, their multitude, do gape for thirst.", "darby": "Therefore my people are led away captive from lack of knowledge, and their nobility die of famine, and their multitude are parched with thirst.", "twenty": "", "jps": "Therefore My people are gone into captivity, for want of knowledge; and their honourable men are famished, and their multitude are parched with thirst.", "acv": "Therefore my people have gone into captivity for lack of knowledge, and their honorable men are famished, and their multitude are parched with thirst.", "anderson": "", "haweis": "", "noyes": "Therefore shall my people be led captive, when they think not of it; Their honorable men shall be famished with hunger, And their rich men parched with thirst.", "webster": "Therefore my people have gone into captivity, because [they have] no knowledge: and their honorable men [are] famished, and their multitude dried up with thirst.", "vulgate": "propterea captivus ductus est populus meus quia non habuit scientiam et nobiles eius interierunt fame et multitudo eius siti exaruit;", "brenton": "Therefore my people have been taken captive, because they know not the Lord: and there has been a multitude of dead bodies, because of hunger and of thirst for water."}}, {"v": 14, "ref": "5:14", "o": "לָ/כֵ֗ן הִרְחִ֤יבָה שְּׁאוֹל֙ נַפְשָׁ֔/הּ וּ/פָעֲרָ֥ה פִ֖י/הָ לִ/בְלִי חֹ֑ק וְ/יָרַ֨ד הֲדָרָ֧/הּ וַ/הֲמוֹנָ֛/הּ וּ/שְׁאוֹנָ֖/הּ וְ/עָלֵ֥ז בָּֽ/הּ", "en": {"kjv": "Therefore hell hath enlarged herself, and opened her mouth without measure: and their glory, and their multitude, and their pomp, and he that rejoiceth, shall descend into it.", "web": "Therefore Sheol has enlarged its desire, and opened its mouth without measure; and their glory, their multitude, their pomp, and he who rejoices among them, descend into it.", "bsb": "Therefore Sheol enlarges its throat and opens wide its enormous jaws, and down go Zion’s nobles and masses, her revelers and carousers!", "asv": "Therefore Sheol hath enlarged its desire, and opened its mouth without measure; and their glory, and their multitude, and their pomp, and he that rejoiceth among them, descend into it.", "ylt": "Therefore hath Sheol enlarged herself, And hath opened her mouth without limit. And gone down hath its honour, and its multitude, And its noise, and its exulting one--into her.", "dra": "Therefore hath hell enlarged her soul, and opened her mouth without any bounds, and their strong ones, and their people, and their high and glorious ones shall go down into it.", "bbe": "For this cause the underworld has made wide its throat, opening its mouth without limit: and her glory, and the noise of her masses, and her loud-voiced feasters, will go down into it.", "geneva": "Therefore hell hath inlarged it selfe, and hath opened his mouth, without measure, and their glorie, and their multitude, and their pompe, and hee that reioyceth among them, shall descend into it.", "wycliffe": "Therfor helle alargide his soule, and openyde his mouth with outen ony ende; and strong men therof, and the puple therof, and the hiy men, and gloriouse men therof, schulen go doun to it.", "rotherham": "Therefore, hath hades enlarged her desire, And opened her mouth to its widest,—And their glory, and their multitude and their pomp. and he that is uproarious shall descend thereinto.", "darby": "Therefore doth Sheol enlarge its desire, and open its mouth without measure; and her splendour shall descend [into it], and her multitude, and her tumult, and [all] that is joyful within her.", "twenty": "", "jps": "Therefore the nether-world hath enlarged her desire, and opened her mouth without measure; and down goeth their glory, and their tumult, and their uproar, and he that rejoiceth among them.", "acv": "Therefore Sheol has enlarged its desire, and opened its mouth without measure. And their glory, and their multitude, and their pomp, and he who rejoices among them, descend into it.", "anderson": "", "haweis": "", "noyes": "Therefore doth the under-world enlarge its greedy throat, And stretch open its mouth without measure, And down go her nobility and her wealth, Her busy throng, and all that was joyful within her.", "webster": "Therefore hell hath enlarged herself, and opened her mouth without measure: and their glory, and their multitude, and their pomp, and he that rejoiceth, shall descend into it.", "vulgate": "propterea dilatavit infernus animam suam et aperuit os suum absque ullo termino et descendent fortes eius et populus eius et sublimes gloriosique eius ad eum;", "brenton": "Therefore hell has enlarged its desire and opened its mouth without ceasing: and her glorious and great, and her rich and her pestilent men shall go down into it."}}, {"v": 15, "ref": "5:15", "o": "וַ/יִּשַּׁ֥ח אָדָ֖ם וַ/יִּשְׁפַּל אִ֑ישׁ וְ/עֵינֵ֥י גְבֹהִ֖ים תִּשְׁפַּֽלְנָה", "en": {"kjv": "And the mean man shall be brought down, and the mighty man shall be humbled, and the eyes of the lofty shall be humbled:", "web": "So man is brought low, mankind is humbled, and the eyes of the arrogant ones are humbled;", "bsb": "So mankind will be brought low, and each man humbled; the arrogant will lower their eyes.", "asv": "And the mean man is bowed down, and the great man is humbled, and the eyes of the lofty are humbled:", "ylt": "And bowed down is the low, and humbled the high, And the eyes of the haughty become low,", "dra": "And man shall be brought down, and man shall be humbled, and the eyes of the lofty shall be brought low.", "bbe": "And the poor man's head is bent, and the great man goes down on his face, and the eyes of pride are put to shame:", "geneva": "And man shalbe brought downe, and man shalbe humbled, euen the eyes of the proude shalbe humbled.", "wycliffe": "And a man schal be bowid doun, and a man of age schal be maad low; and the iyen of hiy men schulen be pressid doun.", "rotherham": "And the mean man hath been bowed down And the mighty man hath been humbled,—Yea the looks of the haughty shall be humbled.", "darby": "And the mean man shall be bowed down, and the great man brought low, and the eyes of the lofty shall be brought low;", "twenty": "", "jps": "And man is bowed down, and man is humbled, and the eyes of the lofty are humbled;", "acv": "And the common man is bowed down, and the great man is debased, and the eyes of the lofty are humbled,", "anderson": "", "haweis": "", "noyes": "The mean man shall be bowed down, And the great man shall be brought low, And the eyes of the haughty shall be humbled;", "webster": "And the mean man shall be brought down, and the mighty man shall be humbled, and the eyes of the lofty shall be abased.", "vulgate": "et incurvabitur homo et humiliabitur vir et oculi sublimium deprimentur;", "brenton": "And the mean man shall be brought low, and the great man shall be disgraced, and the lofty eyes shall be brought low."}}, {"v": 16, "ref": "5:16", "o": "וַ/יִּגְבַּ֛ה יְהוָ֥ה צְבָא֖וֹת בַּ/מִּשְׁפָּ֑ט וְ/הָ/אֵל֙ הַ/קָּד֔וֹשׁ נִקְדָּ֖שׁ בִּ/צְדָקָֽה", "en": {"kjv": "But the Lord of hosts shall be exalted in judgment, and God that is holy shall be sanctified in righteousness.", "web": "but Yahweh of Armies is exalted in justice, and God the Holy One is sanctified in righteousness.", "bsb": "But the LORD of Hosts will be exalted by His justice, and the holy God will show Himself holy in righteousness.", "asv": "but Jehovah of hosts is exalted in justice, and God the Holy One is sanctified in righteousness.", "ylt": "And Jehovah of Hosts is high in judgment, And the Holy God sanctified in righteousness,", "dra": "And the Lord of hosts shall be exalted in judgment, and the holy God shall be sanctified in justice.", "bbe": "But the Lord of armies is lifted up as judge, and the Holy God is seen to be holy in righteousness.", "geneva": "And the Lord of hostes shalbe exalted in iudgement, and the holy God shalbe sanctified in iustice.", "wycliffe": "And the Lord of oostis schal be enhaunsid in doom, and hooli God schal be halewid in riytfulnesse.", "rotherham": "But Yahweh of hosts, hath been exalted, in justice,—And the GOD that is holy hath been hallowed in righteousness;", "darby": "and Jehovah of hosts shall be exalted in judgment, and the holyGod hallowed in righteousness.", "twenty": "", "jps": "But HaShem of hosts is exalted through justice, and G-d the Holy One is sanctified through righteousness.", "acv": "but Jehovah of hosts is exalted in justice, and God the Holy One is sanctified in righteousness.", "anderson": "", "haweis": "", "noyes": "Jehovah of hosts shall be exalted through judgment; Yea, God, the Holy One, shall be sanctified through righteousness.", "webster": "But the LORD of hosts shall be exalted in judgment, and God that is holy shall be sanctified in righteousness.", "vulgate": "et exaltabitur Dominus exercituum in iudicio et Deus sanctus sanctificabitur in iustitia;", "brenton": "But the Lord of hosts shall be exalted in judgment, and the holy God shall be glorified in righteousness."}}, {"v": 17, "ref": "5:17", "o": "וְ/רָע֥וּ כְבָשִׂ֖ים כְּ/דָבְרָ֑/ם וְ/חָרְב֥וֹת מֵחִ֖ים גָּרִ֥ים יֹאכֵֽלוּ", "en": {"kjv": "Then shall the lambs feed after their manner, and the waste places of the fat ones shall strangers eat.", "web": "Then the lambs will graze as in their pasture, and strangers will eat the ruins of the rich.", "bsb": "Lambs will graze as in their own pastures, and strangers will feed in the ruins of the wealthy.", "asv": "Then shall the lambs feed as in their pasture, and the waste places of the fat ones shall wanderers eat.", "ylt": "And fed have lambs according to their leading, And waste places of the fat ones Do sojourners consume.", "dra": "And the lambs shall feed according to their order, and strangers shall eat the deserts turned into fruitfulness.", "bbe": "Then the lambs will get food as in their grass-lands, and the fat cattle will be feasting in the waste places.", "geneva": "Then shall the lambes feede after their maner, and the strangers shall eate the desolate places of the fat.", "wycliffe": "And lambren schulen be fed bi her ordre, and comelyngis schulen ete desert places turned in to plentee.", "rotherham": "Then shall the young rams feed where they please,—And, the wastes of the wealthy, shall strangers consume.", "darby": "And the lambs shall feed as on their pasture, and the waste places of the fat ones shall strangers eat.", "twenty": "", "jps": "Then shall the lambs feed as in their pasture, and the waste places of the fat ones shall wanderers eat.", "acv": "Then the lambs shall feed as in their pasture, and wanderers shall eat the waste places of the fat ones.", "anderson": "", "haweis": "", "noyes": "Then shall the lambs feed, as in their own pasture, And the deserted fields of the rich shall strangers consume.", "webster": "Then shall the lambs feed after their manner, and the waste places of the fat ones shall strangers eat.", "vulgate": "et pascentur agni iuxta ordinem suum et deserta in ubertatem versa advenae comedent;", "brenton": "And they that were spoiled shall be fed as bulls, and lambs shall feed on the waste places of them that are taken away."}}, {"v": 18, "ref": "5:18", "o": "ה֛וֹי מֹשְׁכֵ֥י הֶֽ/עָוֺ֖ן בְּ/חַבְלֵ֣י הַ/שָּׁ֑וְא וְ/כַ/עֲב֥וֹת הָ/עֲגָלָ֖ה חַטָּאָֽה", "en": {"kjv": "Woe unto them that draw iniquity with cords of vanity, and sin as it were with a cart rope:", "web": "Woe to those who draw iniquity with cords of falsehood, and wickedness as with cart rope;", "bsb": "Woe to those who draw iniquity with cords of deceit and pull sin along with cart ropes,", "asv": "Woe unto them that draw iniquity with cords of falsehood, and sin as it were with a cart rope;", "ylt": "Woe to those drawing out iniquity with cords of vanity, And as with thick ropes of the cart--sin.", "dra": "Woe to you that draw iniquity with cords of vanity, and sin as the rope of a cart.", "bbe": "Cursed are those who make use of ox-cords for pulling the evil thing, and the bands of a young ox for their sin!", "geneva": "Woe vnto them, that draw iniquitie with cordes of vanitie, and sinne, as with cart ropes:", "wycliffe": "Wo to you that drawen wickydnesse in the cordis of vanyte, and drawen synne as the boond of a wayn; and ye seien,", "rotherham": "Alas! for them Who draw on themselves punishment with cords of falsehood,—And as with waggon-bands, penalty:", "darby": "Woe unto them that draw iniquity with cords of vanity, and sin as with cart-ropes!", "twenty": "", "jps": "Woe unto them that draw iniquity with cords of vanity, and sin as it were with a cart rope,", "acv": "Woe to those who draw iniquity with cords of falsehood, and sin as it were with a cart rope,", "anderson": "", "haweis": "", "noyes": "Woe to them that draw calamity with cords of wickedness, And punishment as with wagon-traces,—", "webster": "Woe to them that draw iniquity with cords of vanity, and sin as it were with a cart-rope:", "vulgate": "vae qui trahitis iniquitatem in funiculis vanitatis et quasi vinculum plaustri peccatum;", "brenton": "Woe to them that draw sins to them as with a long rope, and iniquities as with a thong of the heifer's yoke:"}}, {"v": 19, "ref": "5:19", "o": "הָ/אֹמְרִ֗ים יְמַהֵ֧ר יָחִ֛ישָׁ/ה מַעֲשֵׂ֖/הוּ לְמַ֣עַן נִרְאֶ֑ה וְ/תִקְרַ֣ב וְ/תָב֗וֹאָ/ה עֲצַ֛ת קְד֥וֹשׁ יִשְׂרָאֵ֖ל וְ/נֵדָֽעָה", "en": {"kjv": "That say, Let him make speed, and hasten his work, that we may see it: and let the counsel of the Holy One of Israel draw nigh and come, that we may know it!", "web": "Who say, “Let him make speed, let him hasten his work, that we may see it; and let the counsel of the Holy One of Israel draw near and come, that we may know it!”", "bsb": "to those who say, “Let Him hurry and hasten His work so that we may see it! Let the plan of the Holy One of Israel come so that we may know it!”", "asv": "that say, Let him make speed, let him hasten his work, that we may see it; and let the counsel of the Holy One of Israel draw nigh and come, that we may know it!", "ylt": "Who are saying, `Let Him hurry, Let Him hasten His work, that we may see, And let the counsel of the Holy One of Israel Draw near and come, and we know.'", "dra": "That say: Let him make haste, and let his work come quickly, that we may see it: and let the counsel of the Holy One of Israel come, that we may know it.", "bbe": "Who say, Let him do his work quickly, let him make it sudden, so that we may see it: let the design of the Holy One of Israel come near, so that it may be clear to us.", "geneva": "Which say, Let him make speede: let him hasten his worke, that wee may see it: and let the counsell of the holy one of Israel draw neere and come, that we may knowe it.", "wycliffe": "The werk of hym haaste, and come soone, that we se; and the counsel of the hooli of Israel neiy, and come, and we schulen knowe it.", "rotherham": "Who say—Let his work quicken—let it hasten, That we may see,—And let the purpose of Israel’s Holy One, draw near and come. That we may know!", "darby": "who say, Let him hasten, let him speed his work, that we may see [it]; and let the counsel of the Holy One of Israel draw nigh and come, that we may know it!", "twenty": "", "jps": "That say: 'Let Him make speed, let Him hasten His work, that we may see it; and let the counsel of the Holy One of Israel draw nigh and come, that we may know it!'", "acv": "who say, Let him make speed, let him hasten his work, that we may see it. And let the counsel of the Holy One of Israel draw near and come, that we may know it!", "anderson": "", "haweis": "", "noyes": "Who say, Let him make speed, let him hasten his work that we may see it! Let the purpose of the Holy One of Israel draw near and be fulfilled, that we may know it!", "webster": "That say, Let him make speed, [and] hasten his work, that we may see [it]: and let the counsel of the Holy One of Israel draw nigh and come, that we may know [it]!", "vulgate": "qui dicitis festinet et cito veniat opus eius ut videamus et adpropiet et veniat consilium Sancti Israhel et sciemus illud;", "brenton": "who say, Let him speedily hasten what he will do, that we may see it: and let the counsel of the Holy One of Israel come, that we may know it."}}, {"v": 20, "ref": "5:20", "o": "ה֣וֹי הָ/אֹמְרִ֥ים לָ/רַ֛ע ט֖וֹב וְ/לַ/טּ֣וֹב רָ֑ע שָׂמִ֨ים חֹ֤שֶׁךְ לְ/אוֹר֙ וְ/א֣וֹר לְ/חֹ֔שֶׁךְ שָׂמִ֥ים מַ֛ר לְ/מָת֖וֹק וּ/מָת֥וֹק לְ/מָֽר", "en": {"kjv": "Woe unto them that call evil good, and good evil; that put darkness for light, and light for darkness; that put bitter for sweet, and sweet for bitter!", "web": "Woe to those who call evil good, and good evil; who put darkness for light, and light for darkness; who put bitter for sweet, and sweet for bitter!", "bsb": "Woe to those who call evil good and good evil, who turn darkness to light and light to darkness, who replace bitter with sweet and sweet with bitter.", "asv": "Woe unto them that call evil good, and good evil; that put darkness for light, and light for darkness; that put bitter for sweet, and sweet for bitter!", "ylt": "Woe to those saying to evil `good,' And to good `evil,' Putting darkness for light, and light for darkness, Putting bitter for sweet, and sweet for bitter.", "dra": "Woe to you that call evil good, and good evil: that put darkness for light, and light for darkness: that put bitter for sweet, and sweet for bitter.", "bbe": "Cursed are those who give the name of good to evil, and of evil to what is good: who make light dark, and dark light: who make bitter sweet, and sweet bitter!", "geneva": "Woe vnto them that speake good of euill, and euill of good, which put darkenes for light, and light for darkenes, that put bitter for sweete, and sweete for sowre.", "wycliffe": "Wo to you that seien yuel good, and good yuel; and putten derknessis liyt, and liyt derknessis; and putten bittir thing in to swete, and swete thing in to bittir.", "rotherham": "Alas! for them Who call evil good and good evil,—Who put darkness for light and light for darkness, Who put bitter for sweet and sweet for bitter.", "darby": "Woe unto them who call evil good, and good evil; who put darkness for light, and light for darkness; who put bitter for sweet, and sweet for bitter!", "twenty": "", "jps": "Woe unto them that call evil good, and good evil; that change darkness into light, and light into darkness; that change bitter into sweet, and sweet into bitter!", "acv": "Woe to those who call evil good, and good evil, who put darkness for light, and light for darkness, who put bitter for sweet, and sweet for bitter!", "anderson": "", "haweis": "", "noyes": "Woe to them that call evil good, and good evil, That put darkness for light, and light for darkness, That put bitter for sweet, and sweet for bitter!", "webster": "Woe to them that call evil good, and good evil; that put darkness for light, and light for darkness; that put bitter for sweet, and sweet for bitter!", "vulgate": "vae qui dicitis malum bonum et bonum malum ponentes tenebras lucem et lucem tenebras ponentes amarum in dulce et dulce in amarum;", "brenton": "Woe to them that call evil good, and good evil; who make darkness light, and light darkness; who make bitter sweet, and sweet bitter."}}, {"v": 21, "ref": "5:21", "o": "ה֖וֹי חֲכָמִ֣ים בְּ/עֵֽינֵי/הֶ֑ם וְ/נֶ֥גֶד פְּנֵי/הֶ֖ם נְבֹנִֽים", "en": {"kjv": "Woe unto them that are wise in their own eyes, and prudent in their own sight!", "web": "Woe to those who are wise in their own eyes, and prudent in their own sight!", "bsb": "Woe to those who are wise in their own eyes and clever in their own sight.", "asv": "Woe unto them that are wise in their own eyes, and prudent in their own sight!", "ylt": "Woe to the wise in their own eyes, And--before their own faces--intelligent!", "dra": "Woe to you that are wise in your own eyes, and prudent in your own conceits.", "bbe": "Cursed are those who seem wise to themselves, and who take pride in their knowledge!", "geneva": "Woe vnto them that are wise in their owne eyes, and prudent in their owne sight.", "wycliffe": "Wo to you that ben wise men in youre iyen, and ben prudent bifor you silf.", "rotherham": "Alas for them Who are wise in their own eyes,—And in their own sight, are prudent.", "darby": "Woe unto them that are wise in their own eyes, and intelligent in their own esteem!", "twenty": "", "jps": "Woe unto them that are wise in their own eyes, and prudent in their own sight!", "acv": "Woe to those who are wise in their own eyes, and prudent in their own sight!", "anderson": "", "haweis": "", "noyes": "Woe to them that are wise in their own eyes, And prudent in their own conceit!", "webster": "Woe to [them that are] wise in their own eyes, and prudent in their own sight!", "vulgate": "vae qui sapientes estis in oculis vestris et coram vobismet ipsis prudentes;", "brenton": "Woe to them that are wise in their own conceit, and knowing in their own sight."}}, {"v": 22, "ref": "5:22", "o": "ה֕וֹי גִּבּוֹרִ֖ים לִ/שְׁתּ֣וֹת יָ֑יִן וְ/אַנְשֵׁי חַ֖יִל לִ/מְסֹ֥ךְ שֵׁכָֽר", "en": {"kjv": "Woe unto them that are mighty to drink wine, and men of strength to mingle strong drink:", "web": "Woe to those who are mighty to drink wine, and champions at mixing strong drink;", "bsb": "Woe to those who are heroes in drinking wine and champions in mixing strong drink,", "asv": "Woe unto them that are mighty to drink wine, and men of strength to mingle strong drink;", "ylt": "Woe to the mighty to drink wine, And men of strength to mingle strong drink.", "dra": "Woe to you that are mighty to drink wine, and stout men at drunkenness.", "bbe": "Cursed are those who are strong to take wine, and great in making mixed drinks!", "geneva": "Wo vnto them that are mightie to drinke wine, and to them that are strong to powre in strong drinke:", "wycliffe": "Wo to you that ben myyti to drynke wyn, and ben stronge to meddle drunkenesse;", "rotherham": "Alas for them Who are heroes to drink wine,—And men of valour to mingle strong drink,", "darby": "Woe unto them that are mighty for drinking wine, and men valiant to mix strong drink;", "twenty": "", "jps": "Woe unto them that are mighty to drink wine, and men of strength to mingle strong drink;", "acv": "Woe to those who are mighty to drink wine, and men of strength to mingle strong drink,", "anderson": "", "haweis": "", "noyes": "Woe to them that are valiant to drink wine, And men of might to mingle strong drink!", "webster": "Woe to [them that are] mighty to drink wine, and men of strength to mingle strong drink:", "vulgate": "vae qui potentes estis ad bibendum vinum et viri fortes ad miscendam ebrietatem;", "brenton": "Woe to the strong ones of you that drink wine, and the mighty ones that mingle strong drink:"}}, {"v": 23, "ref": "5:23", "o": "מַצְדִּיקֵ֥י רָשָׁ֖ע עֵ֣קֶב שֹׁ֑חַד וְ/צִדְקַ֥ת צַדִּיקִ֖ים יָסִ֥ירוּ מִמֶּֽ/נּוּ", "en": {"kjv": "Which justify the wicked for reward, and take away the righteousness of the righteous from him!", "web": "who acquit the guilty for a bribe, but deny justice for the innocent!", "bsb": "who acquit the guilty for a bribe and deprive the innocent of justice.", "asv": "that justify the wicked for a bribe, and take away the righteousness of the righteous from him!", "ylt": "Declaring righteous the wicked for a bribe, And the righteousness of the righteous They turn aside from him.", "dra": "That justify the wicked for gifts, and take away the justice of the just from him.", "bbe": "Who for a reward give support to the cause of the sinner, and who take away the righteousness of the upright from him.", "geneva": "Which iustifie the wicked for a rewarde, and take away the righteousnesse of the righteous from him.", "wycliffe": "and ye iustifien a wickid man for yiftis, and ye taken awei the riytfulnesse of a iust man fro hym.", "rotherham": "Who justify the lawless, for a bribe,—Whereas the righteousness of the righteous, they take from him.", "darby": "who justify the wicked for a bribe, and turn away the righteousness of the righteous from them!", "twenty": "", "jps": "That justify the wicked for a reward, and take away the righteousness of the righteous from him!", "acv": "who justify the wicked for rewards, and take away the justice of the righteous man from him!", "anderson": "", "haweis": "", "noyes": "That clear the guilty for a reward, And take away from the righteous his right!", "webster": "Who justify the wicked for reward, and take away the righteousness of the righteous from him!", "vulgate": "qui iustificatis impium pro muneribus et iustitiam iusti aufertis ab eo;", "brenton": "who justify the ungodly for rewards, and take away the righteousness of the righteous."}}, {"v": 24, "ref": "5:24", "o": "לָ/כֵן֩ כֶּ/אֱכֹ֨ל קַ֜שׁ לְשׁ֣וֹן אֵ֗שׁ וַ/חֲשַׁ֤שׁ לֶֽהָבָה֙ יִרְפֶּ֔ה שָׁרְשָׁ/ם֙ כַּ/מָּ֣ק יִֽהְיֶ֔ה וּ/פִרְחָ֖/ם כָּ/אָבָ֣ק יַעֲלֶ֑ה כִּ֣י מָאֲס֗וּ אֵ֚ת תּוֹרַת֙ יְהוָ֣ה צְבָא֔וֹת וְ/אֵ֛ת אִמְרַ֥ת קְדֽוֹשׁ יִשְׂרָאֵ֖ל נִאֵֽצוּ", "en": {"kjv": "Therefore as the fire devoureth the stubble, and the flame consumeth the chaff, so their root shall be as rottenness, and their blossom shall go up as dust: because they have cast away the law of the Lord of hosts, and despised the word of the Holy One of Israel.", "web": "Therefore as the tongue of fire devours the stubble, and as the dry grass sinks down in the flame, so their root shall be as rottenness, and their blossom shall go up as dust; because they have rejected the law of Yahweh of Armies, and despised the word of the Holy One of Israel.", "bsb": "Therefore, as a tongue of fire consumes the straw, and as dry grass shrivels in the flame, so their roots will decay and their blossoms will blow away like dust; for they have rejected the instruction of the LORD of Hosts and despised the word of the Holy One of Israel.", "asv": "Therefore as the tongue of fire devoureth the stubble, and as the dry grass sinketh down in the flame, so their root shall be as rottenness, and their blossom shall go up as dust; because they have rejected the law of Jehovah of hosts, and despised the word of the Holy One of Israel.", "ylt": "Therefore, as a tongue of fire devoureth stubble, And flaming hay falleth, Their root is as muck, And their flower as dust goeth up. Because they have rejected the law of Jehovah of Hosts, And the saying of the Holy One of Israel despised.", "dra": "Therefore as the tongue of the fire devoureth the stubble, and the heat of the flame consumeth it: so shall their root be as ashes, and their bud shall go up as dust: for they have cast away the law of the Lord of hosts, and have blasphemed the word of the Holy One of Israel.", "bbe": "For this cause, as the waste of the grain is burned up by tongues of fire, and as the dry grass goes down before the flame, so their root will be like the dry stems of grain, and their flower will go up in dust: because they have gone against the law of the Lord of armies, and have given no honour to the word of the Holy One of Israel.", "geneva": "Therefore as the flame of fire deuoureth the stubble, and as the chaffe is cosumed of the flame: so their roote shalbe as rottennesse, and their bud shall rise vp like dust, because they haue cast off the Lawe of the Lord of hostes, and contemned the word of the holy one of Israel.", "wycliffe": "For this thing, as the tunge of fier deuourith stobil, and the heete of flawme brenneth, so the roote of hem schal be as a deed sparcle, and the seed of hem schal stie as dust; for thei castiden awei the lawe of the Lord of oostis, and blasfemyden the speche of the hooli of Israel.", "rotherham": "Therefore, As a tongue of fire, eateth up straw, And a flame reduceth, dry grass, to powder, Their root, like rottenness, shall become, And their blossom, like dust shall ascend,—Because they refused the law of Yahweh of hosts, And the utterance of the Holy One of Israel, they despised.", "darby": "Therefore as a tongue of fire devoureth the stubble, and dry grass sinketh down in the flame, their root shall be as rottenness, and their blossom shall go up as dust; for they have rejected the law of Jehovah of hosts, and despised the word of the Holy One of Israel.", "twenty": "", "jps": "Therefore as the tongue of fire devoureth the stubble, and as the chaff is consumed in the flame, so their root shall be as rottenness, and their blossom shall go up as dust; because they have rejected the law of HaShem of hosts, and contemned the word of the Holy One of Israel.", "acv": "Therefore as the tongue of fire devours the stubble, and as the dry grass sinks down in the flame, so their root shall be as rottenness, and their blossom shall go up as dust, because they have rejected the law of Jehovah of hosts, and despised the word of the Holy One of Israel.", "anderson": "", "haweis": "", "noyes": "Therefore, as fire devours stubble, And as the withered grass sinks into the flame, So their root shall become rottenness, And their blossom shall fly up like dust. For they have despised the law of Jehovah of hosts, And contemned the word of the Holy One of Israel.", "webster": "Therefore as the fire devoureth the stubble, and the flame consumeth the chaff, [so] their root shall be as rottenness, and their blossom shall go up as dust: because they have cast away the law of the LORD of hosts, and despised the word of the Holy One of Israel.", "vulgate": "propter hoc sicut devorat stipulam lingua ignis et calor flammae exurit sic radix eorum quasi favilla erit et germen eorum ut pulvis ascendet abiecerunt enim legem Domini exercituum et eloquium Sancti Israhel blasphemaverunt;", "brenton": "Therefore as stubble shall be burnt by a coal of fire, and shall be consumed by a violent flame, their root shall be as chaff, and their flower shall go up as dust: for they rejected the law of the Lord of hosts, and insulted the word of the Holy One of Israel."}}, {"v": 25, "ref": "5:25", "o": "עַל כֵּ֡ן חָרָה֩ אַף יְהוָ֨ה בְּ/עַמּ֜/וֹ וַ/יֵּ֣ט יָד֧/וֹ עָלָ֣י/ו וַ/יַּכֵּ֗/הוּ וַֽ/יִּרְגְּזוּ֙ הֶֽ/הָרִ֔ים וַ/תְּהִ֧י נִבְלָתָ֛/ם כַּ/סּוּחָ֖ה בְּ/קֶ֣רֶב חוּצ֑וֹת בְּ/כָל זֹאת֙ לֹא שָׁ֣ב אַפּ֔/וֹ וְ/ע֖וֹד יָד֥/וֹ נְטוּיָֽה", "en": {"kjv": "Therefore is the anger of the Lord kindled against his people, and he hath stretched forth his hand against them, and hath smitten them: and the hills did tremble, and their carcases were torn in the midst of the streets. For all this his anger is not turned away, but his hand is stretched out still.", "web": "Therefore Yahweh’s anger burns against his people, and he has stretched out his hand against them, and has struck them. The mountains tremble, and their dead bodies are as refuse in the midst of the streets. For all this, his anger is not turned away, but his hand is still stretched out.", "bsb": "Therefore the anger of the LORD burns against His people; His hand is raised against them to strike them down. The mountains quake, and the corpses lay like refuse in the streets. Despite all this, His anger is not turned away; His hand is still upraised.", "asv": "Therefore is the anger of Jehovah kindled against his people, and he hath stretched forth his hand against them, and hath smitten them; and the mountains tremble, and their dead bodies are as refuse in the midst of the streets. For all this his anger is not turned away, but his hand is stretched out still.", "ylt": "Therefore hath the anger of Jehovah burned among His people, And He stretcheth out His hand against it, And smiteth it, and the mountains tremble, And their carcase is as filth in the midst of the out-places. With all this His anger did not turn back, And still His hand is stretched out!", "dra": "Therefore is the wrath of the Lord kindled against his people, and he hath stretched out his hand upon them, and struck them: and the mountains were troubles, and their carcasses became as dung in the midst of the streets. For after this his anger is not turned away, but his hand is stretched out still.", "bbe": "For this reason the wrath of the Lord has been burning against his people, and his hand has been stretched out against them in punishment, and the hills were shaking, and their dead bodies were like waste in the open places of the town.", "geneva": "Therefore is the wrath of the Lord kindled against his people, and hee hath stretched out his hand vpon them, and hath smitten them that the mountaines did tremble: and their carkases were torne in the middes of the streetes, and for all this his wrath was not turned away, but his hande was stretched out still.", "wycliffe": "Therfor the strong veniaunce of the Lord was wrooth ayens his puple, and he stretchide forth his hond on it, and smoot it; and hillis weren disturblid, and the deed bodies of hem weren maad as a toord in the myddis of stretis. In alle these thingis the stronge vengeaunce of him was not turned awei, but yit his hond was stretchid forth.", "rotherham": "For this cause, did the anger of Yahweh kindle upon his own people, And he stretched out his hand against them and smote them—So that the mountains, trembled, And, their dead bodies, served, for fuel in the midst of the streets. For all this, hath his anger, not turned back, But still, is his hand outstretched,", "darby": "Therefore is the anger of Jehovah kindled against his people, and he hath stretched out his hand against them and hath smitten them; and the mountains trembled, and their carcases are become as dung in the midst of the streets. For all this his anger is not turned away, and his hand is stretched out still.", "twenty": "", "jps": "Therefore is the anger of HaShem kindled against His people, and He hath stretched forth His hand against them, and hath smitten them, and the hills did tremble, and their carcasses were as refuse in the midst of the streets. For all this His anger is not turned away, but His hand is stretched out still.", "acv": "Therefore the anger of Jehovah is kindled against his people, and he has stretched forth his hand against them, and has smitten them. And the mountains tremble, and their dead bodies are as refuse in the midst of the streets. For all this his anger is not turned away, but his hand is stretched out still.", "anderson": "", "haweis": "", "noyes": "Therefore is the anger of Jehovah kindled against his people; He stretcheth forth his hand against them, and smiteth them, so that the mountains tremble, And their carcasses are as dung in the midst of the streets; For all this his anger is not turned away, But his hand is stretched out still.", "webster": "Therefore is the anger of the LORD kindled against his people, and he hath stretched forth his hand against them, and hath smitten them: and the hills trembled, and their carcasses [were] torn in the midst of the streets. For all this his anger is not turned away, but his hand [is] stretched out still.", "vulgate": "ideo iratus est furor Domini in populo suo et extendit manum suam super eum et percussit eum et conturbati sunt montes et facta sunt morticina eorum quasi stercus in medio platearum in omnibus his non est aversus furor eius sed adhuc manus eius extenta;", "brenton": "Therefore the Lord of hosts was greatly angered against his people, and he reached forth his hand upon them, and smote them: and the mountains were troubled, and their carcasses were as dung in the midst of the way: yet for all this his anger has not been turned away, but his hand is yet raised."}}, {"v": 26, "ref": "5:26", "o": "וְ/נָֽשָׂא נֵ֤ס לַ/גּוֹיִם֙ מֵ/רָח֔וֹק וְ/שָׁ֥רַק ל֖/וֹ מִ/קְצֵ֣ה הָ/אָ֑רֶץ וְ/הִנֵּ֥ה מְהֵרָ֖ה קַ֥ל יָבֽוֹא", "en": {"kjv": "And he will lift up an ensign to the nations from far, and will hiss unto them from the end of the earth: and, behold, they shall come with speed swiftly:", "web": "He will lift up a banner to the nations from far, and he will whistle for them from the end of the earth. Behold, they will come speedily and swiftly.", "bsb": "He lifts a banner for the distant nations and whistles for those at the ends of the earth. Behold—how speedily and swiftly they come!", "asv": "And he will lift up an ensign to the nations from far, and will hiss for them from the end of the earth; and, behold, they shall come with speed swiftly.", "ylt": "And He lifted up an ensign to nations afar off, And hissed to it from the end of the earth, And lo, with haste, swift it cometh.", "dra": "And he will lift up a sign to the nations afar off, and will whistle to them from the ends of the earth: and behold they shall come with speed swiftly.", "bbe": "And he will let a flag be lifted up as a sign to a far-off nation, whistling to them from the ends of the earth: and they will come quickly and suddenly.", "geneva": "And he will lift vp a signe vnto the nations a farre, and wil hisse vnto them from the ende of the earth: and beholde, they shall come hastily with speede.", "wycliffe": "And he schal reise a signe among naciouns afer, and he schal hisse to hym fro the endis of erthe; and lo! he schal haaste, and schal come swiftli.", "rotherham": "Therefore will he lift up an ensign to the nations afar off, And signal for him from the end of the earth,—And lo! with hot haste, will he come:", "darby": "And he will lift up a banner to the nations afar off, and will hiss for one from the end of the earth; and behold, it will come rapidly [and] lightly.", "twenty": "", "jps": "And He will lift up an ensign to the nations from far, and will hiss unto them from the end of the earth; and, behold, they shall come with speed swiftly;", "acv": "And he will lift up an ensign to the nations from far, and will whistle for them from the end of the earth, and, behold, they shall come with speed swiftly.", "anderson": "", "haweis": "", "noyes": "He lifteth up a banner for the nations afar off, He whistleth for them from the ends of the earth, And behold, they haste, and come swiftly.", "webster": "And he will lift up an ensign to the nations from afar, and will hiss to them from the end of the earth: and behold, they shall come with speed swiftly:", "vulgate": "et levabit signum nationibus procul et sibilabit ad eum de finibus terrae et ecce festinus velociter veniet;", "brenton": "Therefore shall he lift up a signal to the nations that are afar, and shall hiss for them from the end of the earth; and, behold, they are coming very quickly."}}, {"v": 27, "ref": "5:27", "o": "אֵין עָיֵ֤ף וְ/אֵין כּוֹשֵׁל֙ בּ֔/וֹ לֹ֥א יָנ֖וּם וְ/לֹ֣א יִישָׁ֑ן וְ/לֹ֤א נִפְתַּח֙ אֵז֣וֹר חֲלָצָ֔י/ו וְ/לֹ֥א נִתַּ֖ק שְׂר֥וֹךְ נְעָלָֽי/ו", "en": {"kjv": "None shall be weary nor stumble among them; none shall slumber nor sleep; neither shall the girdle of their loins be loosed, nor the latchet of their shoes be broken:", "web": "No one shall be weary nor stumble among them; no one shall slumber nor sleep; neither shall the belt of their waist be untied, nor the strap of their sandals be broken:", "bsb": "None of them grows weary or stumbles; no one slumbers or sleeps. No belt is loose and no sandal strap is broken.", "asv": "None shall be weary nor stumble among them; none shall slumber nor sleep; neither shall the girdle of their loins be loosed, nor the latchet of their shoes be broken:", "ylt": "There is none weary, nor stumbling in it, It doth not slumber, nor sleep, Nor opened hath been the girdle of its loins, Nor drawn away the latchet of its sandals.", "dra": "There is none that shall faint, nor labour among them: they shall not slumber nor sleep, neither shall the girdle of their loins be loosed, nor the latchet of their shoes be broken.", "bbe": "There is no weariness among them, and no man is feeble-footed: they come without resting or sleeping, and the cord of their shoes is not broken.", "geneva": "None shall faint nor fall among them: none shall slumber nor sleepe, neither shall the girdle of his loynes be loosed, nor the latchet of his shooes be broken:", "wycliffe": "Noon is failynge nethir trauelynge in that oost; he schal not nappe, nether slepe, nether the girdil of his reynes schal be vndo, nether the lace of his scho schal be brokun.", "rotherham": "None shall be weary, and none shall stumble in his midst, He shall neither slumber nor sleep,—Nor shall be loosened, the girdle of his loins, Nor snapped, the thong of his sandals:", "darby": "None among them is weary, none stumbleth; they slumber not, nor sleep; none hath the girdle of his loins loosed, nor the thong of his sandals broken;", "twenty": "", "jps": "None shall be weary nor stumble among them; none shall slumber nor sleep; neither shall the girdle of their loins be loosed, nor the latchet of their shoes be broken;", "acv": "None shall be weary nor stumble among them. None shall slumber nor sleep, nor shall the belt of their loins be loosed, nor the latchet of their shoes be broken,", "anderson": "", "haweis": "", "noyes": "None among them is weary, and none stumbleth; None slumbereth nor sleepeth; The girdle of their loins is not loosed, Nor the latchet of their shoes broken.", "webster": "None shall be weary nor stumble among them; none shall slumber nor sleep; neither shall the girdle of their loins be loosed, nor the latchet of their shoes be broken:", "vulgate": "non est deficiens neque laborans in eo non dormitabit neque dormiet neque solvetur cingulum renum eius nec rumpetur corrigia calciamenti eius;", "brenton": "They shall not hunger nor be weary, neither shall they slumber nor sleep; neither shall they loose their girdles from their loins, neither shall their shoe-latchets be broken."}}, {"v": 28, "ref": "5:28", "o": "אֲשֶׁ֤ר חִצָּי/ו֙ שְׁנוּנִ֔ים וְ/כָל קַשְּׁתֹתָ֖י/ו דְּרֻכ֑וֹת פַּרְס֤וֹת סוּסָי/ו֙ כַּ/צַּ֣ר נֶחְשָׁ֔בוּ וְ/גַלְגִּלָּ֖י/ו כַּ/סּוּפָֽה", "en": {"kjv": "Whose arrows are sharp, and all their bows bent, their horses’ hoofs shall be counted like flint, and their wheels like a whirlwind:", "web": "whose arrows are sharp, and all their bows bent. Their horses’ hoofs will be like flint, and their wheels like a whirlwind.", "bsb": "Their arrows are sharpened, and all their bows are strung. The hooves of their horses are like flint; their chariot wheels are like a whirlwind.", "asv": "whose arrows are sharp, and all their bows bent; their horses’ hoofs shall be accounted as flint, and their wheels as a whirlwind:", "ylt": "Whose arrows are sharp, and all its bows bent, Hoofs of its horses as flint have been reckoned, And its wheels as a hurricane!", "dra": "Their arrows are sharp, and all their bows are bent. The hoofs of their horses shall be like the flint, and their wheels like the violence of a tempest.", "bbe": "Their arrows are sharp, and every bow is bent: the feet of their horses are like rock, and their wheels are like a rushing storm.", "geneva": "Whose arrowes shall be sharpe, and all his bowes bent: his horse hoofes shall be thought like flint, and his wheeles like a whirlewinde.", "wycliffe": "Hise arowis ben scharpe, and alle hise bowis ben bent; the houys of hise horsis ben as a flynt, and hise wheelis ben as the feersnesse of tempest.", "rotherham": "Whose arrows, are sharpened, and all his bows, bent,—The hoofs of his horses, like flint, are accounted, And, his wheels, [are] like a storm-wind:", "darby": "their arrows are sharp, and all their bows bent; their horses' hoofs are reckoned as the flint, and their wheels as a whirlwind.", "twenty": "", "jps": "Whose arrows are sharp, and all their bows bent; their horses' hoofs shall be counted like flint, and their wheels like a whirlwind;", "acv": "whose arrows are sharp, and all their bows bent. Their horses' hoofs shall be accounted as flint, and their wheels as a whirlwind.", "anderson": "", "haweis": "", "noyes": "Their arrows are sharp, And all their bows bent; The hoofs of their horses are like flint, And their wheels like a whirlwind.", "webster": "Whose arrows [are] sharp, and all their bows bent, their horses' hoofs shall be counted like flint, and their wheels like a whirlwind:", "vulgate": "sagittae eius acutae et omnes arcus eius extenti ungulae equorum eius ut silex et rotae eius quasi impetus tempestatis;", "brenton": "Whose arrows are sharp, and their bows bent; their horses' hoofs are counted as solid rock: their chariot-wheels are as a storm."}}, {"v": 29, "ref": "5:29", "o": "שְׁאָגָ֥ה ל֖/וֹ כַּ/לָּבִ֑יא ו/שאג יִשְׁאַ֨ג כַּ/כְּפִירִ֤ים וְ/יִנְהֹם֙ וְ/יֹאחֵ֣ז טֶ֔רֶף וְ/יַפְלִ֖יט וְ/אֵ֥ין מַצִּֽיל", "en": {"kjv": "Their roaring shall be like a lion, they shall roar like young lions: yea, they shall roar, and lay hold of the prey, and shall carry it away safe, and none shall deliver it.", "web": "Their roaring will be like a lioness. They will roar like young lions. Yes, they shall roar, and seize their prey and carry it off, and there will be no one to deliver.", "bsb": "Their roaring is like that of a lion; they roar like young lions. They growl and seize their prey; they carry it away from deliverance.", "asv": "their roaring shall be like a lioness, they shall roar like young lions; yea, they shall roar, and lay hold of the prey, and carry it away safe, and there shall be none to deliver.", "ylt": "Its roaring is like a lioness, It roareth like young lions, And it howleth, and seizeth prey, And carrieth away safely, and there is none delivering.", "dra": "Their roaring like that of a lion, they shall roar like young lions: yea they shall roar, and take hold of the prey, and they shall keep fast hold of it, and there shall be none to deliver it.", "bbe": "The sound of their armies will be like the voice of a lion, and their war-cry like the noise of young lions: with loud cries they will come down on their food and will take it away safely, and there will be no one to take it out of their hands.", "geneva": "His roaring shalbe like a lyon, and he shall roare like lyons whelpes: they shall roare, and lay holde of the praye: they shall take it away, and none shall deliuer it.", "wycliffe": "His roryng schal be as of lioun; he schal rore as the whelpis of liouns; and he schal gnaste, and schal holde prey, and schal biclippe, and noon schal be, that schal delyuere.", "rotherham": "A roar, hath he, like a lioness,—He will roar like wild lions—And will growl, and lay hold on prey, and carry into safety, and there be none to deliver.", "darby": "Their roaring is like a lioness, they roar as the young lions; yea, they growl, and snatch the prey, and carry it away safe, and there is none to deliver;", "twenty": "", "jps": "Their roaring shall be like a lion, they shall roar like young lions, yea, they shall roar, and lay hold of the prey, and carry it away safe, and there shall be none to deliver.", "acv": "Their roaring shall be like a lioness. They shall roar like young lions. Yea, they shall roar, and lay hold of the prey, and carry it away safe, and there shall be none to deliver.", "anderson": "", "haweis": "", "noyes": "Their roaring is like the roaring of the lion; They roar like young lions; They roar, and seize the prey; They bear it away, and none can rescue it.", "webster": "Their roaring [shall be] like a lion, they shall roar like young lions: yes, they shall roar, and lay hold of the prey, and shall carry [it] away safe, and none shall deliver [it].", "vulgate": "rugitus eius ut leonis rugiet ut catuli leonum et frendet et tenebit praedam et amplexabitur et non erit qui eruat;", "brenton": "They rage as lions, and draw nigh as a lion's whelps: and he shall seize, and roar as a wild beast, and he shall cast them forth, and there shall be none to deliver them."}}, {"v": 30, "ref": "5:30", "o": "וְ/יִנְהֹ֥ם עָלָ֛י/ו בַּ/יּ֥וֹם הַ/ה֖וּא כְּ/נַהֲמַת יָ֑ם וְ/נִבַּ֤ט לָ/אָ֨רֶץ֙ וְ/הִנֵּה חֹ֔שֶׁךְ צַ֣ר וָ/א֔וֹר חָשַׁ֖ךְ בַּ/עֲרִיפֶֽי/הָ", "en": {"kjv": "And in that day they shall roar against them like the roaring of the sea: and if one look unto the land, behold darkness and sorrow, and the light is darkened in the heavens thereof.", "web": "They will roar against them in that day like the roaring of the sea. If one looks to the land behold, darkness and distress. The light is darkened in its clouds.", "bsb": "In that day they will roar over it, like the roaring of the sea. If one looks over the land, he will see darkness and distress; even the light will be obscured by clouds.", "asv": "And they shall roar against them in that day like the roaring of the sea: and if one look unto the land, behold, darkness and distress; and the light is darkened in the clouds thereof.", "ylt": "And it howleth against it in that day as the howling of a sea, And it hath looked attentively to the land, And lo, darkness--distress, And light hath been darkened by its abundance!", "dra": "And they shall make a noise against them that day, like the roaring of the sea; we shall look towards the land, and behold darkness of tribulation, and the light is darkened with the mist thereof.", "bbe": "And his voice will be loud over him in that day like the sounding of the sea: and if a man's eyes are turned to the earth, it is all dark and full of trouble; and the light is made dark by thick clouds.", "geneva": "And in that day they shall roare vpon them, as the roaring of the sea: and if they looke vnto the earth, beholde darkenesse, and sorowe, and the light shalbe darkened in their skie.", "wycliffe": "And he schal sowne on it in that dai, as doith the soun of the see; we schulen biholde in to the erthe, and lo! derknessis of tribulacioun, and liyt is maad derk in the derknesse therof.", "rotherham": "Yea he will growl at him in that day, like the growling of the sea,—Though he look hard for the land, lo! the darkness of distress, Yea the light, hath grown dark in its clouds!", "darby": "and they shall roar against them in that day like the roaring of the sea. And if one look upon the earth, behold darkness [and] distress, and the light is darkened in the heavens thereof.", "twenty": "", "jps": "And they shall roar against them in that day like the roaring of the sea; and if one look unto the land, behold darkness and distress, and the light is darkened in the skies thereof.", "acv": "And they shall roar against them in that day like the roaring of the sea. And if a man looks to the land, behold, darkness and distress, and the light is darkened in the clouds of it.", "anderson": "", "haweis": "", "noyes": "Yea, in that day shall they roar against them like the roaring of the sea; And if one look to the land, behold darkness and sorrow, And the light is darkened by its clouds.", "webster": "And in that day they shall roar against them like the roaring of the sea: and if [one] looketh to the land, behold darkness [and] sorrow, and the light is darkened in its heavens.", "vulgate": "et sonabit super eum in die illa sicut sonitus maris aspiciemus in terram et ecce tenebrae tribulationis et lux obtenebrata est in caligine eius;", "brenton": "And he shall roar on account of them in that day, as the sound of the swelling sea; and they shall look to the land, and, behold, there shall be thick darkness in their perplexity."}}]}, {"c": 6, "verses": [{"v": 1, "ref": "6:1", "o": "בִּ/שְׁנַת מוֹת֙ הַ/מֶּ֣לֶךְ עֻזִּיָּ֔הוּ וָ/אֶרְאֶ֧ה אֶת אֲדֹנָ֛/י יֹשֵׁ֥ב עַל כִּסֵּ֖א רָ֣ם וְ/נִשָּׂ֑א וְ/שׁוּלָ֖י/ו מְלֵאִ֥ים אֶת הַ/הֵיכָֽל", "en": {"kjv": "In the year that king Uzziah died I saw also the Lord sitting upon a throne, high and lifted up, and his train filled the temple.", "web": "In the year that king Uzziah died, I saw the Lord sitting on a throne, high and lifted up; and his train filled the temple.", "bsb": "In the year that King Uzziah died, I saw the Lord seated on a throne, high and exalted; and the train of His robe filled the temple.", "asv": "In the year that king Uzziah died I saw the Lord sitting upon a throne, high and lifted up; and his train filled the temple.", "ylt": "In the year of the death of king Uzziah--I see the Lord, sitting on a throne, high and lifted up, and His train is filling the temple.", "dra": "In the year that king Ozias died, I saw the Lord sitting upon a throne high and elevated: and his train filled the temple.", "bbe": "In the year of King Uzziah's death I saw the Lord seated in his place, high and lifted up, and the Temple was full of the wide skirts of his robe.", "geneva": "In the yeere of the death of King Vzziah, I saw also the Lord sitting vpon an high throne, and lifted vp, and the lower partes thereof filled the Temple.", "wycliffe": "In the yeer in which the kyng Osie was deed, Y siy the Lord sittynge on an hiy seete, and reisid; and the hous was ful of his mageste, and tho thingis that weren vndur hym, filliden the temple.", "rotherham": "In the year that King Uzziah died, I saw My Lord, sitting upon a throne high and lifted up, and, his skirts, did fill the temple,", "darby": "In the year of the death of king Uzziah, I saw the Lord sitting upon a throne, high and lifted up; and his train filled the temple.", "twenty": "", "jps": "In the year that king Uzziah died I saw the L-rd sitting upon a throne high and lifted up, and His train filled the temple.", "acv": "In the year that king Uzziah died I saw the Lord sitting upon a throne, high and lifted up, and his train filled the temple.", "anderson": "", "haweis": "", "noyes": "In the year in which King Uzziah died, I saw the Lord sitting on a throne high and lifted up, and the train of his robe filled the temple.", "webster": "In the year that king Uzziah died I saw also the Lord sitting upon a throne, high and elevated, and his train filled the temple.", "vulgate": "in anno quo mortuus est rex Ozias vidi Dominum sedentem super solium excelsum et elevatum et ea quae sub eo erant implebant templum;", "brenton": "And it came to pass in the year in which king Ozias died, that I saw the Lord sitting on a high and exalted throne, and the house was full of his glory."}}, {"v": 2, "ref": "6:2", "o": "שְׂרָפִ֨ים עֹמְדִ֤ים מִ/מַּ֨עַל֙ ל֔/וֹ שֵׁ֧שׁ כְּנָפַ֛יִם שֵׁ֥שׁ כְּנָפַ֖יִם לְ/אֶחָ֑ד בִּ/שְׁתַּ֣יִם יְכַסֶּ֣ה פָנָ֗י/ו וּ/בִ/שְׁתַּ֛יִם יְכַסֶּ֥ה רַגְלָ֖י/ו וּ/בִ/שְׁתַּ֥יִם יְעוֹפֵֽף", "en": {"kjv": "Above it stood the seraphims: each one had six wings; with twain he covered his face, and with twain he covered his feet, and with twain he did fly.", "web": "Above him stood the seraphim. Each one had six wings. With two he covered his face. With two he covered his feet. With two he flew.", "bsb": "Above Him stood seraphim, each having six wings: With two wings they covered their faces, with two they covered their feet, and with two they were flying.", "asv": "Above him stood the seraphim: each one had six wings; with twain he covered his face, and with twain he covered his feet, and with twain he did fly.", "ylt": "Seraphs are standing above it: six wings hath each one; with two each covereth its face, and with two each covereth its feet, and with two each flieth.", "dra": "Upon it stood the seraphims: the one had six wings, and the other had six wings: with two they covered his face, and with two they covered his feet, and with two they flew.", "bbe": "Over him were the winged ones: every one had six wings; two for covering his face, two for covering his feed, and two for flight.", "geneva": "The Seraphims stoode vpon it: euery one had sixe wings: with twaine he couered his face, and with twaine hee couered his feete, and with twaine he did flie.", "wycliffe": "Serafyn stoden on it, sixe wyngis weren to oon, and sixe wyngis to the tothir; with twei wyngis thei hiliden the face of hym, and with twei wyngis thei hiliden the feet of hym, and with twei wyngis thei flowen.", "rotherham": "Seraphim, were standing above him; six wings severally, had each one,—With twain, he covered his face And with twain, he covered his feet And with twain, he did fly.", "darby": "Seraphim were standing above him: each had six wings; with twain he covered his face, and with twain he covered his feet, and with twain he flew.", "twenty": "", "jps": "Above Him stood the seraphim; each one had six wings: with twain he covered his face and with twain he covered his feet, and with twain he did fly.", "acv": "Above him stood the seraphim. Each one had six wings, with two he covered his face, and with two he covered his feet, and with two he flew.", "anderson": "", "haweis": "", "noyes": "Around him stood seraphs; each one of them had six wings; with two he covered his face, with two he covered his feet, and with two he did fly.", "webster": "Above it stood seraphim: each one had six wings; with two he covered his face, and with two he covered his feet, and with two he flew.", "vulgate": "seraphin stabant super illud sex alae uni et sex alae alteri duabus velabant faciem eius et duabus velabant pedes eius et duabus volabant;", "brenton": "And seraphs stood round about him: each one had six wings: and with two they covered their face, and with two they covered their feet, and with two they flew."}}, {"v": 3, "ref": "6:3", "o": "וְ/קָרָ֨א זֶ֤ה אֶל זֶה֙ וְ/אָמַ֔ר קָד֧וֹשׁ קָד֛וֹשׁ קָד֖וֹשׁ יְהוָ֣ה צְבָא֑וֹת מְלֹ֥א כָל הָ/אָ֖רֶץ כְּבוֹדֽ/וֹ", "en": {"kjv": "And one cried unto another, and said, Holy, holy, holy, is the Lord of hosts: the whole earth is full of his glory.", "web": "One called to another, and said, “Holy, holy, holy, is Yahweh of Armies! The whole earth is full of his glory!”", "bsb": "And they were calling out to one another: “Holy, holy, holy is the LORD of Hosts; all the earth is full of His glory.”", "asv": "And one cried unto another, and said, Holy, holy, holy, is Jehovah of hosts: the whole earth is full of his glory.", "ylt": "And this one hath called unto that, and hath said: `Holy, Holy, Holy, is Jehovah of Hosts, The fulness of all the earth is His glory.'", "dra": "And they cried one to another, and said: Holy, holy, holy, the Lord God of hosts, all the earth is full of his glory,", "bbe": "And one said in a loud voice to another, Holy, holy, holy, is the Lord of armies: all the earth is full of his glory.", "geneva": "And one cryed to another, and sayde, Holy, holy, holy is the Lord of hostes: the whole world is full of his glory.", "wycliffe": "And thei crieden `the toon to the tother, and seiden, Hooli, hooli, hooli is the Lord God of oostis; al erthe is ful of his glorie.", "rotherham": "And they continued crying out one to another, and said, Holy—holy—holy, is Yahweh of hosts,—the fulness of the whole earth, is his glory.", "darby": "And one called to the other and said, Holy, holy, holy is Jehovah of hosts; the whole earth is full of his glory!", "twenty": "", "jps": "And one called unto another, and said: Holy, holy, holy, is HaShem of hosts; the whole earth is full of His glory.", "acv": "And one cried to another, and said, Holy, holy, holy, is Jehovah of hosts. The whole earth is full of his glory.", "anderson": "", "haweis": "", "noyes": "And one called to another, and said: Holy, holy, holy is Jehovah of hosts; The whole earth is full of his glory.", "webster": "And one cried to another, and said, Holy, holy, holy [is] the LORD of hosts: the whole earth [is] full of his glory.", "vulgate": "et clamabant alter ad alterum et dicebant sanctus sanctus sanctus Dominus exercituum plena est omnis terra gloria eius;", "brenton": "And one cried to the other, and they said, Holy, holy, holy is the Lord of hosts: the whole earth is full of his glory."}}, {"v": 4, "ref": "6:4", "o": "וַ/יָּנֻ֨עוּ֙ אַמּ֣וֹת הַ/סִּפִּ֔ים מִ/קּ֖וֹל הַ/קּוֹרֵ֑א וְ/הַ/בַּ֖יִת יִמָּלֵ֥א עָשָֽׁן", "en": {"kjv": "And the posts of the door moved at the voice of him that cried, and the house was filled with smoke.", "web": "The foundations of the thresholds shook at the voice of him who called, and the house was filled with smoke.", "bsb": "At the sound of their voices the doorposts and thresholds shook, and the temple was filled with smoke.", "asv": "And the foundations of the thresholds shook at the voice of him that cried, and the house was filled with smoke.", "ylt": "And the posts of the thresholds are moved by the voice of him who is calling, and the house is full of smoke.", "dra": "And the lintels of the doors were moved at the voice of him that cried, and the house was filled with smoke.", "bbe": "And the bases of the door-pillars were shaking at the sound of his cry, and the house was full of smoke.", "geneva": "And the lintles of the doore cheekes moued at the voyce of him that cryed, and the house was filled with smoke.", "wycliffe": "And the lyntels aboue of the herris were moued togidere of the vois of the criere, and the hous was fillid with smoke.", "rotherham": "And the foundations of the porch, were moved at the voice of him that cried,—and the house, was filled with smoke.", "darby": "And the foundations of the thresholds shook at the voice of him that cried, and the house was filled with smoke.", "twenty": "", "jps": "And the posts of the door were moved at the voice of them that called, and the house was filled with smoke.", "acv": "And the foundations of the thresholds shook at the voice of him who cried, and the house was filled with vapor.", "anderson": "", "haweis": "", "noyes": "And the foundations of the thresholds were shaken with the voice of their cry. And the temple was filled with smoke.", "webster": "And the posts of the door moved at the voice of him that cried, and the house was filled with smoke.", "vulgate": "et commota sunt superliminaria cardinum a voce clamantis et domus impleta est fumo;", "brenton": "And the lintel shook at the voice they uttered, and the house was filled with smoke."}}, {"v": 5, "ref": "6:5", "o": "וָ/אֹמַ֞ר אֽוֹי לִ֣/י כִֽי נִדְמֵ֗יתִי כִּ֣י אִ֤ישׁ טְמֵֽא שְׂפָתַ֨יִם֙ אָנֹ֔כִי וּ/בְ/תוֹךְ֙ עַם טְמֵ֣א שְׂפָתַ֔יִם אָנֹכִ֖י יוֹשֵׁ֑ב כִּ֗י אֶת הַ/מֶּ֛לֶךְ יְהוָ֥ה צְבָא֖וֹת רָא֥וּ עֵינָֽ/י", "en": {"kjv": "Then said I, Woe is me! for I am undone; because I am a man of unclean lips, and I dwell in the midst of a people of unclean lips: for mine eyes have seen the King, the Lord of hosts.", "web": "Then I said, “Woe is me! For I am undone, because I am a man of unclean lips, and I dwell in the midst of a people of unclean lips: for my eyes have seen the King, Yahweh of Armies!”", "bsb": "Then I said: “Woe is me, for I am ruined, because I am a man of unclean lips dwelling among a people of unclean lips; for my eyes have seen the King, the LORD of Hosts.”", "asv": "Then said I, Woe is me! for I am undone; because I am a man of unclean lips, and I dwell in the midst of a people of unclean lips: for mine eyes have seen the King, Jehovah of hosts.", "ylt": "And I say, `Woe to me, for I have been silent, For a man--unclean of lips am I, And in midst of a people unclean of lips I am dwelling, Because the King, Jehovah of Hosts, have my eyes seen.'", "dra": "And I said: Woe is me, because I have held my peace; because I am a man of unclean lips, and I dwell in the midst of a people that hath unclean lips, and I have seen with my eyes the King the Lord of hosts.", "bbe": "Then I said, The curse is on me, and my fate is destruction; for I am a man of unclean lips, living among a people of unclean lips; for my eyes have seen the King, the Lord of armies.", "geneva": "Then I sayd, Wo is me: for I am vndone, because I am a man of polluted lips, and I dwell in the middes of a people of polluted lips: for mine eyes haue seene the King and Lord of hostes.", "wycliffe": "And Y seide, Wo to me, for Y was stille; for Y am a man defoulid in lippis, and Y dwelle in the myddis of the puple hauynge defoulid lippis, and Y siy with myn iyen the kyng Lord of oostis.", "rotherham": "Then said I—Woe to me!—for I am undone, Because a man of unclean lips, am, I, And in the midst of a people of unclean lips, do I dwell,—For the King. Yahweh of hosts, have mine eyes seen!", "darby": "And I said, Woe unto me! for I am undone; for I am a man of unclean lips, and I dwell in the midst of a people of unclean lips: for mine eyes have seen the King, Jehovah of hosts.", "twenty": "", "jps": "Then said I: Woe is me! for I am undone; because I am a man of unclean lips, and I dwell in the midst of a people of unclean lips; for mine eyes have seen the King, HaShem of hosts.", "acv": "Then I said, Woe is me! For I am undone, because I am a man of unclean lips, and I dwell in the midst of a people of unclean lips. For my eyes have seen the King, Jehovah of hosts.", "anderson": "", "haweis": "", "noyes": "Then I said, Alas for me! I am undone! For I am a man of unclean lips, and dwell among a people of unclean lips, and mine eyes have seen the King, Jehovah of hosts.", "webster": "Then said I, Woe [is] me! for I am undone; because I [am] a man of unclean lips, and I dwell in the midst of a people of unclean lips: for my eyes have seen the King, the LORD of hosts.", "vulgate": "et dixi vae mihi quia tacui quia vir pollutus labiis ego sum et in medio populi polluta labia habentis ego habito et Regem Dominum exercituum vidi oculis meis;", "brenton": "And I said, Woe is me, for I am pricked to the heart; for being a man, and having unclean lips, I dwell in the midst of a people having unclean lips; and I have seen with mine eyes the King, the Lord of hosts."}}, {"v": 6, "ref": "6:6", "o": "וַ/יָּ֣עָף אֵלַ֗/י אֶחָד֙ מִן הַ/שְּׂרָפִ֔ים וּ/בְ/יָד֖/וֹ רִצְפָּ֑ה בְּ/מֶ֨לְקַחַ֔יִם לָקַ֖ח מֵ/עַ֥ל הַ/מִּזְבֵּֽחַ", "en": {"kjv": "Then flew one of the seraphims unto me, having a live coal in his hand, which he had taken with the tongs from off the altar:", "web": "Then one of the seraphim flew to me, having a live coal in his hand, which he had taken with the tongs from off the altar.", "bsb": "Then one of the seraphim flew to me, and in his hand was a glowing coal that he had taken with tongs from the altar.", "asv": "Then flew one of the seraphim unto me, having a live coal in his hand, which he had taken with the tongs from off the altar:", "ylt": "And flee unto me doth one of the seraphs, and in his hand a burning coal, (with tongs he hath taken it from off the altar,)", "dra": "And one of the seraphims flew to me, and in his hand was a live coal, which he had taken with the tongs off the altar.", "bbe": "Then a winged one came to me with a burning coal in his hand, which he had taken from off the altar with the fire-spoon.", "geneva": "Then flewe one of the Seraphims vnto me with an hote cole in his hand, which he had taken from the altar with the tongs:", "wycliffe": "And oon of serafyn flei to me, and a brennynge cole was in his hond, which cole he hadde take with a tonge fro the auter.", "rotherham": "Then flew unto me one of the seraphim, And in his hand, a live coal,—With tongs, had he taken it from off the altar.", "darby": "And one of the seraphim flew unto me, and he had in his hand a glowing coal, which he had taken with the tongs from off the altar;", "twenty": "", "jps": "Then flew unto me one of the seraphim, with a glowing stone in his hand, which he had taken with the tongs from off the altar;", "acv": "Then one of the seraphim flew to me, having a live coal in his hand, which he had taken with the tongs from off the altar.", "anderson": "", "haweis": "", "noyes": "Then flew one of the seraphs to me, having in his hands a glowing stone, which he had taken with the tongs from the altar.", "webster": "Then one of the seraphim flew to me, having a live coal in his hand, [which] he had taken with the tongs from off the altar:", "vulgate": "et volavit ad me unus de seraphin et in manu eius calculus quem forcipe tulerat de altari;", "brenton": "And there was sent to me one of the seraphs, and he had in his hand a coal, which he had taken off the altar with the tongs:"}}, {"v": 7, "ref": "6:7", "o": "וַ/יַּגַּ֣ע עַל פִּ֔/י וַ/יֹּ֕אמֶר הִנֵּ֛ה נָגַ֥ע זֶ֖ה עַל שְׂפָתֶ֑י/ךָ וְ/סָ֣ר עֲוֺנֶ֔/ךָ וְ/חַטָּאתְ/ךָ֖ תְּכֻפָּֽר", "en": {"kjv": "And he laid it upon my mouth, and said, Lo, this hath touched thy lips; and thine iniquity is taken away, and thy sin purged.", "web": "He touched my mouth with it, and said, “Behold, this has touched your lips; and your iniquity is taken away, and your sin forgiven.”", "bsb": "And with it he touched my mouth and said: “Now that this has touched your lips, your iniquity is removed and your sin is atoned for.”", "asv": "and he touched my mouth with it, and said, Lo, this hath touched thy lips; and thine iniquity is taken away, and thy sin forgiven.", "ylt": "and he striketh against my mouth, and saith: `Lo, this hath stricken against thy lips, And turned aside is thine iniquity, And thy sin is covered.'", "dra": "And he touched my mouth, and said: Behold this hath touched thy lips, and thy iniquities shall be taken away, and thy sin shall be cleansed.", "bbe": "And after touching my mouth with it, he said, See, your lips have been touched with this; and your evil is taken away, and you are made clean from sin.", "geneva": "And he touched my mouth, and sayd, Loe, this hath touched thy lips, and thine iniquitie shall be taken away, and thy sinne shalbe purged.", "wycliffe": "And he touchide my mouth, and seide, Lo! Y haue touchid thi lippis with this cole, and thi wickidnesse schal be don awei, and thi synne schal be clensid.", "rotherham": "Then touched he my mouth, and said—Lo! this hath touched thy lips,—Thus shall be taken away, thine iniquity, And, thy sin, by propitiation be covered.", "darby": "and he made it touch my mouth, and said, Behold, this hath touched thy lips; and thine iniquity is taken away, and thy sin expiated.", "twenty": "", "jps": "and he touched my mouth with it, and said: Lo, this hath touched thy lips; and thine iniquity is taken away, and thy sin expiated.", "acv": "And he touched my mouth with it, and said, Lo, this has touched thy lips, and thine iniquity is taken away, and thy sin forgiven.", "anderson": "", "haweis": "", "noyes": "And he touched my mouth, and said, Behold, this toucheth thy lips, and thine iniquity is taken away, and thy sin is expiated.", "webster": "And he laid [it] upon my mouth, and said, Lo, this hath touched thy lips; and thy iniquity is taken away, and thy sin purged.", "vulgate": "et tetigit os meum et dixit ecce tetigit hoc labia tua et auferetur iniquitas tua et peccatum tuum mundabitur;", "brenton": "and he touched my mouth, and said, Behold, this has touched thy lips, and will take away thine iniquities, and will purge off thy sins."}}, {"v": 8, "ref": "6:8", "o": "וָ/אֶשְׁמַ֞ע אֶת ק֤וֹל אֲדֹנָ/י֙ אֹמֵ֔ר אֶת מִ֥י אֶשְׁלַ֖ח וּ/מִ֣י יֵֽלֶךְ לָ֑/נוּ וָ/אֹמַ֖ר הִנְ/נִ֥י שְׁלָחֵֽ/נִי", "en": {"kjv": "Also I heard the voice of the Lord, saying, Whom shall I send, and who will go for us? Then said I, Here am I; send me.", "web": "I heard the Lord’s voice, saying, “Whom shall I send, and who will go for us?” Then I said, “Here I am. Send me!”", "bsb": "Then I heard the voice of the Lord saying: “Whom shall I send? Who will go for Us?” And I said: “Here am I. Send me!”", "asv": "And I heard the voice of the Lord, saying, Whom shall I send, and who will go for us? Then I said, Here am I; send me.", "ylt": "And I hear the voice of the Lord, saying: `Whom do I send? and who doth go for Us?' And I say, `Here am I, send me.'", "dra": "And I heard the voice of the Lord, saying: Whom shall I send? and who shall go for us? And I said: Lo, here am I, send me.", "bbe": "And the voice of the Lord came to my ears, saying, Whom am I to send, and who will go for us? Then I said, Here am I, send me.", "geneva": "Also I heard the voyce of the Lord, saying, Whome shall I send? and who shall goe for vs? Then I sayd, Here am I, send me.", "wycliffe": "And Y herde the vois of the Lord, seiynge, Whom schal Y sende, and who schal go to you? And Y seide, Lo! Y; sende thou me.", "rotherham": "Then heard I the voice of My Lord, saying, Whom shall I send? And who will go for us? And I said—Here am I—send me.", "darby": "And I heard the voice of the Lord saying, Whom shall I send, and who will go for us? And I said, Here am I; send me.", "twenty": "", "jps": "And I heard the voice of the L-rd, saying: Whom shall I send, and who will go for us? Then I said: 'Here am I; send me.'", "acv": "And I heard the voice of the Lord, saying, Whom shall I send, and who will go for us? Then I said, Lo, send me.", "anderson": "", "haweis": "", "noyes": "And I heard the voice of the Lord, saying, Whom shall I send, and who will go for us? And I said: Behold, here am I; send me!", "webster": "Also I heard the voice of the Lord, saying, Whom shall I send, and who will go for us? Then said I, Here [am] I; send me.", "vulgate": "et audivi vocem Domini dicentis quem mittam et quis ibit nobis et dixi ecce ego sum mitte me;", "brenton": "And I heard the voice of the Lord, saying, Whom shall I send, and who will go to this people? And I said, behold, I am here, send me. And he said, Go, and say to this people,"}}, {"v": 9, "ref": "6:9", "o": "וַ/יֹּ֕אמֶר לֵ֥ךְ וְ/אָמַרְתָּ֖ לָ/עָ֣ם הַ/זֶּ֑ה שִׁמְע֤וּ שָׁמ֨וֹעַ֙ וְ/אַל תָּבִ֔ינוּ וּ/רְא֥וּ רָא֖וֹ וְ/אַל תֵּדָֽעוּ", "en": {"kjv": "And he said, Go, and tell this people, Hear ye indeed, but understand not; and see ye indeed, but perceive not.", "web": "He said, “Go, and tell this people, ‘You hear indeed, but don’t understand; and you see indeed, but don’t perceive.’", "bsb": "And He replied: “Go and tell this people, ‘Be ever hearing, but never understanding; be ever seeing, but never perceiving.’", "asv": "And he said, Go, and tell this people, Hear ye indeed, but understand not; and see ye indeed, but perceive not.", "ylt": "And He saith, `Go, and thou hast said to this people, Hear ye--to hear, and ye do not understand, And see ye--to see, and ye do not know.", "dra": "And he said: Go, and thou shalt say to this people: Hearing, hear, and understand not: and see the vision, and know it not.", "bbe": "And he said, Go, and say to this people, You will go on hearing, but learning nothing; you will go on seeing, but without getting wiser.", "geneva": "And he sayd, Goe, and say vnto this people, Ye shall heare in deede, but ye shall not vnderstand: ye shall plainely see, and not perceiue.", "wycliffe": "And he seide, Go thou, and thou schalt seie to this puple, Ye herynge here, and nyle ye vndurstonde; and se ye the profesie, and nyle ye knowe.", "rotherham": "Then said he—Go and say unto this people,—Hear on but do not discern, See on but do not perceive:", "darby": "And he said, Go; and thou shalt say unto this people, Hearing ye shall hear and shall not understand, and seeing ye shall see and shall not perceive.", "twenty": "", "jps": "And He said: 'Go, and tell this people: hear ye indeed, but understand not; and see ye indeed, but perceive not.", "acv": "And he said, Go, and tell this people, Hear ye indeed, but do not understand, and see ye indeed, but do not perceive.", "anderson": "", "haweis": "", "noyes": "And he said: Go, and say thou to this people, Hear ye, indeed, but understand not; See ye, indeed, but perceive not!", "webster": "And he said, Go, and tell this people, Hear ye indeed, but understand not; and see ye indeed, but perceive not.", "vulgate": "et dixit vade et dices populo huic audite audientes et nolite intellegere et videte visionem et nolite cognoscere;", "brenton": "Ye shall hear indeed, but ye shall not understand; and ye shall see indeed, but ye shall not perceive."}}, {"v": 10, "ref": "6:10", "o": "הַשְׁמֵן֙ לֵב הָ/עָ֣ם הַ/זֶּ֔ה וְ/אָזְנָ֥י/ו הַכְבֵּ֖ד וְ/עֵינָ֣י/ו הָשַׁ֑ע פֶּן יִרְאֶ֨ה בְ/עֵינָ֜י/ו וּ/בְ/אָזְנָ֣י/ו יִשְׁמָ֗ע וּ/לְבָב֥/וֹ יָבִ֛ין וָ/שָׁ֖ב וְ/רָ֥פָא לֽ/וֹ", "en": {"kjv": "Make the heart of this people fat, and make their ears heavy, and shut their eyes; lest they see with their eyes, and hear with their ears, and understand with their heart, and convert, and be healed.", "web": "Make the heart of this people fat. Make their ears heavy, and shut their eyes; lest they see with their eyes, and hear with their ears, and understand with their heart, and turn again, and be healed.”", "bsb": "Make the hearts of this people calloused; deafen their ears and close their eyes. Otherwise they might see with their eyes, hear with their ears, understand with their hearts, and turn and be healed.”", "asv": "Make the heart of this people fat, and make their ears heavy, and shut their eyes; lest they see with their eyes, and hear with their ears, and understand with their heart, and turn again, and be healed.", "ylt": "Declare fat the heart of this people, And its ears declare heavy, And its eyes declare dazzled, Lest it see with its eyes, And with its ears hear, and its heart consider, And it hath turned back, and hath health.'", "dra": "Blind the heart of this people, and make their ears heavy, and shut their eyes: lest they see with their eyes, and hear with their ears, and understand with their heart, and be converted and I heal them.", "bbe": "Make the hearts of this people fat, and let their ears be stopped, and their eyes shut; for fear that they may see with their eyes, and be hearing with their ears, and their heart may become wise, and they may be turned to me and made well.", "geneva": "Make the heart of this people fatte, make their eares heauie, and shut their eyes, lest they see with their eyes, and heare with their eares, and vnderstand with their hearts, and conuert, and he heale them.", "wycliffe": "Make thou blynde the herte of this puple, and aggrege thou the eeris therof, and close thou the iyen therof; lest perauenture it se with hise iyen, and here with hise eeris, and vndurstonde with his herte, and it be conuertid, and Y make it hool.", "rotherham": "Stupefy thou the heart of this people, And their ears, make thou heavy, And their eyes, overspread,—Lest they see with their eyes And with their ears, should hear, And their heart should discern and come back. And they be healed.", "darby": "Make the heart of this people fat, and make their ears heavy, and blind their eyes; lest they see with their eyes, and hear with their ears, and understand with their heart, and be converted, and healed.", "twenty": "", "jps": "Make the heart of this people fat, and make their ears heavy, and shut their eyes; lest they, seeing with their eyes, and hearing with their ears, and understanding with their heart, return, and be healed.'", "acv": "Make the heart of this people fat, and make their ears heavy, and shut their eyes, lest they see with their eyes, and hear with their ears, and understand with their heart, and turn, and be healed.", "anderson": "", "haweis": "", "noyes": "Make the heart of this people gross; Make their ears dull, and blind their eyes; That they may not see with their eyes, nor hear with their ears, Nor perceive with their hearts, and turn, and be healed.", "webster": "Make the heart of this people fat, and make their ears heavy, and shut their eyes; lest they see with their eyes, and hear with their ears, and understand with their heart, and convert, and be healed.", "vulgate": "excaeca cor populi huius et aures eius adgrava et oculos eius claude ne forte videat oculis suis et auribus suis audiat et corde suo intellegat et convertatur et sanem eum;", "brenton": "For the heart of this people has become gross, and their ears are dull of hearing, and their eyes have they closed; lest they should see with their eyes, and hear with their ears, and understand with their heart, and be converted, and I should heal them."}}, {"v": 11, "ref": "6:11", "o": "וָ/אֹמַ֕ר עַד מָתַ֖י אֲדֹנָ֑/י וַ/יֹּ֡אמֶר עַ֣ד אֲשֶׁר֩ אִם שָׁא֨וּ עָרִ֜ים מֵ/אֵ֣ין יוֹשֵׁ֗ב וּ/בָתִּים֙ מֵ/אֵ֣ין אָדָ֔ם וְ/הָ/אֲדָמָ֖ה תִּשָּׁאֶ֥ה שְׁמָמָֽה", "en": {"kjv": "Then said I, Lord, how long? And he answered, Until the cities be wasted without inhabitant, and the houses without man, and the land be utterly desolate,", "web": "Then I said, “Lord, how long?” He answered, “Until cities are waste without inhabitant, and houses without man, and the land becomes utterly waste,", "bsb": "Then I asked: “How long, O Lord?” And He replied: “Until the cities lie ruined and without inhabitant, until the houses are left unoccupied and the land is desolate and ravaged,", "asv": "Then said I, Lord, how long? And he answered, Until cities be waste without inhabitant, and houses without man, and the land become utterly waste,", "ylt": "And I say, `Till when, O Lord?' And He saith, `Surely till cities have been wasted without inhabitant, And houses without man, And the ground be wasted--a desolation,", "dra": "And I said: How long, O Lord? And he said: Until the cities be wasted without inhabitant, and the houses without man, and the land shall be left desolate.", "bbe": "Then I said, Lord, how long? And he said in answer, Till the towns are waste and unpeopled, and the houses have no men, and the land becomes completely waste,", "geneva": "Then sayd I, Lord, howe long? And he answered, Vntill the cities be wasted without inhabitant, and the houses without man, and the land be vtterly desolate,", "wycliffe": "And Y seide, Lord, hou long? And he seide, Til citees ben maad desolat with out dwellere, and housis with out man. And the lond schal be left desert,", "rotherham": "Then said I—How long, My Lord? And he said—Until the time that Cities be wasted through having no inhabitant And houses—through having no men, And, the ground, be laid waste unto desolation;", "darby": "And I said, Lord, how long? And he said, Until the cities be wasted, without inhabitant, and the houses without man, and the land become an utter desolation,", "twenty": "", "jps": "Then said I: 'L-rd, how long?' And He answered: 'Until cities be waste without inhabitant, and houses without man, and the land become utterly waste,", "acv": "Then I said, Lord, how long? And he answered, Until cities be waste without inhabitant, and houses without man, and the land become utterly waste,", "anderson": "", "haweis": "", "noyes": "Then said I, How long, Lord? He said: Until the cities be laid waste, so that there be no inhabitant, And the houses, so that there be no man, And the land be left utterly desolate;", "webster": "Then said I, Lord, how long? And he answered, Until the cities shall be wasted without inhabitant, and the houses without man, and the land be utterly desolate;", "vulgate": "et dixi usquequo Domine et dixit donec desolentur civitates absque habitatore et domus sine homine et terra relinquetur deserta;", "brenton": "And I said, How long, O Lord? And he said, Until cities be deserted by reason of their not being inhabited, and the houses by reason of there being no men, and the land shall be left desolate."}}, {"v": 12, "ref": "6:12", "o": "וְ/רִחַ֥ק יְהוָ֖ה אֶת הָ/אָדָ֑ם וְ/רַבָּ֥ה הָ/עֲזוּבָ֖ה בְּ/קֶ֥רֶב הָ/אָֽרֶץ", "en": {"kjv": "And the Lord have removed men far away, and there be a great forsaking in the midst of the land.", "web": "And Yahweh has removed men far away, and the forsaken places are many in the midst of the land.", "bsb": "until the LORD has driven men far away and the land is utterly forsaken.", "asv": "and Jehovah have removed men far away, and the forsaken places be many in the midst of the land.", "ylt": "And Jehovah hath put man far off, And great is the forsaken part in the heart of the land.", "dra": "And the Lord shall remove men far away, and she shall be multiplied that was left in the midst of the earth.", "bbe": "And the Lord has taken men far away, and there are wide waste places in the land.", "geneva": "And the Lord haue remoued men farre away, and there be a great desolation in the mids of the land.", "wycliffe": "and the Lord schal make men fer. And that that was forsakun in the myddil of erthe, schal be multiplied, and yit tithing schal be ther ynne;", "rotherham": "And Yahweh have far removed men,—And great! be the abandonment in the midst of the land.", "darby": "and Jehovah have removed men far away, and the solitude be great in the midst of the land.", "twenty": "", "jps": "And HaShem have removed men far away, and the forsaken places be many in the midst of the land.", "acv": "and Jehovah has removed men far away, and the forsaken places be many in the midst of the land.", "anderson": "", "haweis": "", "noyes": "Until Jehovah have removed the men far away, And there be great desolation in the land.", "webster": "And the LORD shall have removed men far away, and [there be] a great forsaking in the midst of the land.", "vulgate": "et longe faciet Dominus homines et multiplicabitur quae derelicta fuerat in medio terrae;", "brenton": "And after this God shall remove the men far off, and they that are left upon the land shall be multiplied."}}, {"v": 13, "ref": "6:13", "o": "וְ/ע֥וֹד בָּ/הּ֙ עֲשִׂ֣רִיָּ֔ה וְ/שָׁ֖בָה וְ/הָיְתָ֣ה לְ/בָעֵ֑ר כָּ/אֵלָ֣ה וְ/כָ/אַלּ֗וֹן אֲשֶׁ֤ר בְּ/שַׁלֶּ֨כֶת֙ מַצֶּ֣בֶת בָּ֔/ם זֶ֥רַע קֹ֖דֶשׁ מַצַּבְתָּֽ/הּ", "en": {"kjv": "But yet in it shall be a tenth, and it shall return, and shall be eaten: as a teil tree, and as an oak, whose substance is in them, when they cast their leaves: so the holy seed shall be the substance thereof.", "web": "If there is a tenth left in it, that also will in turn be consumed: as a terebinth, and as an oak, whose stock remains when they are felled; so the holy seed is its stock.”", "bsb": "And though a tenth remains in the land, it will be burned again. As the terebinth and oak leave stumps when felled, so the holy seed will be a stump in the land.”", "asv": "And if there be yet a tenth in it, it also shall in turn be eaten up: as a terebinth, and as an oak, whose stock remaineth, when they are felled; so the holy seed is the stock thereof.", "ylt": "And yet in it a tenth, and it hath turned, And hath been for a burning, As a teil-tree, and as an oak, that in falling, Have substance in them, The holy seed is its substance!'", "dra": "And there shall be still a tithing therein, and she shall turn, and shall be made a show as a turpentine tree, and as an oak that spreadeth its branches: that which shall stand therein, shall be a holy seed.", "bbe": "And even if there is still a tenth part in it, it will again be burned, like a tree of the woods whose broken end is still in the earth after the tree has been cut down (the holy seed is the broken end).", "geneva": "But yet in it shalbe a tenth, and shall returne, and shalbe eaten vp as an elme or an oke, which haue a substance in them, when they cast their leaues: so the holy seede shall be the substance thereof.", "wycliffe": "and it schal be conuertid, and it schal be in to schewyng, as a terebynte is, and as an ook, that spredith abrood hise boowis; that schal be hooli seed, that schal stonde ther ynne.", "rotherham": "Yet still shall there be in it a tenth, Though it again be consumed,—Like an oak and like a terebinth Which when felled, have a stock in them, A holy seed, shall be the stock thereof.", "darby": "But a tenth part shall still be therein, and it shall return and be eaten; as the terebinth and as the oak whose trunk [remaineth] after the felling: the holy seed shall be the trunk thereof.", "twenty": "", "jps": "And if there be yet a tenth in it, it shall again be eaten up; as a terebinth, and as an oak, whose stock remaineth, when they cast their leaves, so the holy seed shall be the stock thereof.'", "acv": "And if there be yet a tenth in it, it also shall in turn be eaten up. As a terebinth, and as an oak, whose stock remains when they are felled, so the holy seed is the stock of it.", "anderson": "", "haweis": "", "noyes": "And though there be a tenth part remaining in it, Even this shall again be destroyed; Yet as when the terebinth and the oak are cut down, Their stem remaineth alive, So shall a holy race be the stem of the nation.", "webster": "But yet in it [shall be] a tenth, and [it] shall return, and shall be eaten: as a teil-tree, and as an oak whose substance [is] in them, when they cast [their leaves]: [so] the holy seed [shall be] the substance of it.", "vulgate": "et adhuc in ea decimatio et convertetur et erit in ostensionem sicut terebinthus et sicuti quercus quae expandit ramos suos semen sanctum erit id quod steterit in ea;", "brenton": "And yet there shall be a tenth upon it, and again it shall be for a spoil, as a turpentine tree, and as an acorn when it falls out of its husk."}}]}, {"c": 7, "verses": [{"v": 1, "ref": "7:1", "o": "וַ/יְהִ֡י בִּ/ימֵ֣י אָ֠חָז בֶּן יוֹתָ֨ם בֶּן עֻזִּיָּ֜הוּ מֶ֣לֶךְ יְהוּדָ֗ה עָלָ֣ה רְצִ֣ין מֶֽלֶךְ אֲ֠רָם וּ/פֶ֨קַח בֶּן רְמַלְיָ֤הוּ מֶֽלֶךְ יִשְׂרָאֵל֙ יְר֣וּשָׁלִַ֔ם לַ/מִּלְחָמָ֖ה עָלֶ֑י/הָ וְ/לֹ֥א יָכֹ֖ל לְ/הִלָּחֵ֥ם עָלֶֽי/הָ", "en": {"kjv": "And it came to pass in the days of Ahaz the son of Jotham, the son of Uzziah, king of Judah, that Rezin the king of Syria, and Pekah the son of Remaliah, king of Israel, went up toward Jerusalem to war against it, but could not prevail against it.", "web": "In the days of Ahaz the son of Jotham, the son of Uzziah, king of Judah, Rezin the king of Syria, and Pekah the son of Remaliah, king of Israel, went up to Jerusalem to war against it, but could not prevail against it.", "bsb": "Now in the days that Ahaz son of Jotham, the son of Uzziah, was king of Judah, Rezin king of Aram marched up to wage war against Jerusalem. He was accompanied by Pekah son of Remaliah the king of Israel, but he could not overpower the city.", "asv": "And it came to pass in the days of Ahaz the son of Jotham, the son of Uzziah, king of Judah, that Rezin the king of Syria, and Pekah the son of Remaliah, king of Israel, went up to Jerusalem to war against it, but could not prevail against it.", "ylt": "And it cometh to pass in the days of Ahaz, son of Jotham, son of Uzziah, king of Judah, gone up hath Rezin king of Aram, and Pekah, son of Remaliah, king of Israel, to Jerusalem, to battle against it, and he is not able to fight against it.", "dra": "And it came to pass in the days of Achaz the son of Joathan, the son of Ozias, king of Juda, that Rasin king of Syria and Phacee the son of Romelia king of Israel, came up to Jerusalem, to fight against it: but they could not prevail over it.", "bbe": "Now it came about in the days of Ahaz, the son of Jotham, the son of Uzziah, king of Judah, that Rezin, the king of Aram, and Pekah, the son of Remaliah, the king of Israel, came up to Jerusalem to make war against it, but were not able to overcome it.", "geneva": "And in the dayes of Ahaz, the sonne of Iotham, the sonne of Vzziah king of Iudah, Rezin the King of Aram came vp, and Pekah the sonne of Remaliah King of Israel, to Ierusalem to fight against it, but he could not ouercome it.", "wycliffe": "And it was don in the daies of Achas, the sone of Joathan, the sone of Osias, kyng of Juda, Rasyn, the kyng of Sirie, and Facee, the sone of Romelie, the kyng of Israel, stieden to Jerusalem, for to fiyte ayens it; and thei myyten not ouercome it.", "rotherham": "And it came to pass in the days of Ahaz son of Jotham son of Uzziah king of Judah, that Rezin king of Syria, and Pekah son of Remaliah king of Israel, came up, to Jerusalem, to war against it, but could not prevail against it.", "darby": "And it came to pass in the days of Ahaz, the son of Jotham, the son of Uzziah, king of Judah, [that] Rezin the king of Syria, and Pekah the son of Remaliah, king of Israel, came up to Jerusalem to make war against it, but they were not able to fight against it.", "twenty": "", "jps": "And it came to pass in the days of Ahaz the son of Jotham, the son of Uzziah, king of Judah, that Rezin the king of Aram, and Pekah the son of Remaliah, king of Israel, went up to Jerusalem to war against it; but could not prevail against it.", "acv": "And it came to pass in the days of Ahaz the son of Jotham, the son of Uzziah, king of Judah, that Rezin the king of Syria, and Pekah the son of Remaliah, king of Israel, went up to Jerusalem to war against it, but could not prevail against it.", "anderson": "", "haweis": "", "noyes": "In the time of Ahaz, the son of Jotham, the son of Uzziah, king of Judah, Rezin, king of Syria, and Pekah, the son of Remaliah, king of Israel, came up against Jerusalem to besiege it; but he could not prevail against it.", "webster": "And it came to pass in the days of Ahaz the son of Jotham, the son of Uzziah, king of Judah, [that] Rezin the king of Syria, and Pekah the son of Remaliah, king of Israel, went up towards Jerusalem to war against it, but could not prevail against it.", "vulgate": "et factum est in diebus Ahaz filii Ioatham filii Oziae regis Iuda ascendit Rasin rex Syriae et Phacee filius Romeliae rex Israhel in Hierusalem ad proeliandum contra eam et non potuerunt debellare eam;", "brenton": "And it came to pass in the days of Achaz the son of Joatham, the son of Ozias, king of Juda, there came up Rasim king of Aram, and Phakee son of Romelias, king of Israel, against Jerusalem to war against it, but they could not take it."}}, {"v": 2, "ref": "7:2", "o": "וַ/יֻּגַּ֗ד לְ/בֵ֤ית דָּוִד֙ לֵ/אמֹ֔ר נָ֥חָֽה אֲרָ֖ם עַל אֶפְרָ֑יִם וַ/יָּ֤נַע לְבָב/וֹ֙ וּ/לְבַ֣ב עַמּ֔/וֹ כְּ/נ֥וֹעַ עֲצֵי יַ֖עַר מִ/פְּנֵי רֽוּחַ", "en": {"kjv": "And it was told the house of David, saying, Syria is confederate with Ephraim. And his heart was moved, and the heart of his people, as the trees of the wood are moved with the wind.", "web": "It was told the house of David, saying, “Syria is allied with Ephraim.” His heart trembled, and the heart of his people, as the trees of the forest tremble with the wind.", "bsb": "When it was reported to the house of David that Aram was in league with Ephraim, the hearts of Ahaz and his people trembled like trees in the forest shaken by the wind.", "asv": "And it was told the house of David, saying, Syria is confederate with Ephraim. And his heart trembled, and the heart of his people, as the trees of the forest tremble with the wind.", "ylt": "And it is declared to the house of David, saying, `Aram hath been led towards Ephraim,' And his heart and the heart of his people is moved, like the moving of trees of a forest by the presence of wind.", "dra": "And they told the house of David, saying: Syria hath rested upon Ephraim, and his heart was moved, and the heart of his people, as the trees of the woods are moved with the wind.", "bbe": "And word came to the family of David that Aram had put up its tents in Ephraim. And the king's heart, and the hearts of his people, were moved, like the trees of the wood shaking in the wind.", "geneva": "And it was tolde the house of Dauid, saying, Aram is ioyned with Ephraim: therefore his heart was moued, and the heart of his people, as the trees of the forest are moued by the winde.", "wycliffe": "And thei telden to the hous of Dauid, and seiden, Sirie hath restid on Effraym, and the herte of hym and of his puple was mouyd togidere, as the trees of wodis ben mouyd of the face of the wynd.", "rotherham": "And it was told the house of David, saying, Syria hath settled down upon Ephraim. Then shook his heart, and the heart of his people, as the trees of a forest shake before a wind.", "darby": "And it was told the house of David saying, Syria is allied with Ephraim. Then his heart and the heart of his people shook, as the trees of the forest are shaken with the wind.", "twenty": "", "jps": "And it was told the house of David, saying: 'Aram is confederate with Ephraim.' And his heart was moved, and the heart of his people, as the trees of the forest are moved with the wind.", "acv": "And it was told the house of David, saying, Syria is allied with Ephraim. And his heart trembled, and the heart of his people, as the trees of the forest tremble with the wind.", "anderson": "", "haweis": "", "noyes": "And when it was told the house of David, that the Syrians had encamped in Ephraim, his heart was moved, and the hearts of his people, as the trees of the forest are moved with the wind.", "webster": "And it was told the house of David, saying, Syria is confederate with Ephraim. And his heart was moved, and the heart of his people, as the trees of the wood are moved with the wind.", "vulgate": "et nuntiaverunt domui David dicentes requievit Syria super Ephraim et commotum est cor eius et cor populi eius sicut moventur ligna silvarum a facie venti;", "brenton": "And a message was brought to the house of David, saying, Aram has conspired with Ephraim. And his soul was amazed, and the soul of his people, as in a wood a tree is moved by the wind."}}, {"v": 3, "ref": "7:3", "o": "וַ/יֹּ֣אמֶר יְהוָה֮ אֶֽל יְשַׁעְיָהוּ֒ צֵא נָא֙ לִ/קְרַ֣את אָחָ֔ז אַתָּ֕ה וּ/שְׁאָ֖ר יָשׁ֣וּב בְּנֶ֑/ךָ אֶל קְצֵ֗ה תְּעָלַת֙ הַ/בְּרֵכָ֣ה הָ/עֶלְיוֹנָ֔ה אֶל מְסִלַּ֖ת שְׂדֵ֥ה כוֹבֵֽס", "en": {"kjv": "Then said the Lord unto Isaiah, Go forth now to meet Ahaz, thou, and Shear–jashub thy son, at the end of the conduit of the upper pool in the highway of the fuller’s field;", "web": "Then Yahweh said to Isaiah, “Go out now to meet Ahaz, you, and Shearjashub your son, at the end of the conduit of the upper pool, on the highway of the fuller’s field.", "bsb": "Then the LORD said to Isaiah, “Go out with your son Shear-jashub to meet Ahaz at the end of the aqueduct that feeds the upper pool, on the road to the Launderer’s Field,", "asv": "Then said Jehovah unto Isaiah, Go forth now to meet Ahaz, thou, and Shear-jashub thy son, at the end of the conduit of the upper pool, in the highway of the fuller’s field;", "ylt": "And Jehovah saith unto Isaiah, `Go forth, I pray thee, to meet Ahaz, thou, and Shear-Jashub thy son, unto the end of the conduit of the upper pool, unto the highway of the fuller's field,", "dra": "And the Lord said to Isaiah: Go forth to meet Achaz, thou and Jasub thy son that is left, to the conduit of the upper pool in the way of the fuller's field.", "bbe": "Then the Lord said to Isaiah, Go out now, you and Shear-jashub, your son, and you will come across Ahaz at the end of the stream flowing from the higher pool, in the highway of the washerman's field;", "geneva": "Then sayde the Lord vnto Isaiah, Goe foorth nowe to meete Ahaz (thou and Sheariashub thy sonne) at the ende of the conduit of the vpper poole, in the path of the fullers fielde,", "wycliffe": "And the Lord seide to Isaie, Go thou out, and Jasub, thi sone, which is left, in to the meetyng of Achas, at the laste ende of the water cundijt of the hiyere cisterne, in the weie of the feeld of the fullere.", "rotherham": "Then said Yahweh, unto Isaiah, Go forth, I pray thee, to meet Ahaz, thou, and Shear-jashub thy son,—unto the end of the channel of the upper pool, unto the highway of the fuller’s field;", "darby": "And Jehovah said to Isaiah, Go out now to meet Ahaz, thou and thy son Shear-jashub, at the end of the aqueduct of the upper pool, on the highway of the fuller's field;", "twenty": "", "jps": "Then said HaShem unto Isaiah: 'Go forth now to meet Ahaz, thou, and Shear-jashub thy son, at the end of the conduit of the upper pool, in the highway of the fullers' field;", "acv": "Then Jehovah said to Isaiah, Go forth now to meet Ahaz, thou, and Shear-jashub thy son, at the end of the conduit of the upper pool, in the highway of the fuller's field.", "anderson": "", "haweis": "", "noyes": "Then said Jehovah to Isaiah, Go forth to meet Ahaz, thou and Shear-Jashub thy son, at the end of the aqueduct of the upper pool, in the way to the fuller’s field;", "webster": "Then said the LORD to Isaiah, Go forth now to meet Ahaz, thou, and Shear-jashub thy son, at the end of the conduit of the upper pool in the highway of the fuller's field;", "vulgate": "et dixit Dominus ad Isaiam egredere in occursum Ahaz tu et qui derelictus est Iasub filius tuus ad extremum aquaeductus piscinae superioris in via agri Fullonis;", "brenton": "And the Lord said to Esaias, Go forth to meet Achaz, thou, and thy son Jasub who is left, to the pool of the upper way of the fuller's field."}}, {"v": 4, "ref": "7:4", "o": "וְ/אָמַרְתָּ֣ אֵ֠לָי/ו הִשָּׁמֵ֨ר וְ/הַשְׁקֵ֜ט אַל תִּירָ֗א וּ/לְבָבְ/ךָ֙ אַל יֵרַ֔ךְ מִ/שְּׁנֵ֨י זַנְב֧וֹת הָ/אוּדִ֛ים הָ/עֲשֵׁנִ֖ים הָ/אֵ֑לֶּה בָּ/חֳרִי אַ֛ף רְצִ֥ין וַ/אֲרָ֖ם וּ/בֶן רְמַלְיָֽהוּ", "en": {"kjv": "And say unto him, Take heed, and be quiet; fear not, neither be fainthearted for the two tails of these smoking firebrands, for the fierce anger of Rezin with Syria, and of the son of Remaliah.", "web": "Tell him, ‘Be careful, and keep calm. Don’t be afraid, neither let your heart be faint because of these two tails of smoking torches, for the fierce anger of Rezin and Syria, and of the son of Remaliah.", "bsb": "and say to him: Calm down and be quiet. Do not be afraid or disheartened over these two smoldering stubs of firewood—over the fierce anger of Rezin and Aram and of the son of Remaliah.", "asv": "and say unto him, Take heed, and be quiet; fear not, neither let thy heart be faint, because of these two tails of smoking firebrands, for the fierce anger of Rezin and Syria, and of the son of Remaliah.", "ylt": "and thou hast said unto him: `Take heed, and be quiet, fear not, And let not thy heart be timid, Because of these two tails of smoking brands, For the fierceness of the anger of Rezin and Aram, And the son of Remaliah.", "dra": "And thou shalt say to him: See thou be quiet: fear not, and let not thy heart be afraid of the two tails of these firebrands, smoking with the wrath of the fury of Rasin king of Syria, and of the son of Romelia.", "bbe": "And say to him, Take care and be quiet; have no fear, and do not let your heart be feeble, because of these two ends of smoking fire-wood, because of the bitter wrath of Rezin and Aram, and of the son of Remaliah.", "geneva": "And say vnto him, Take heede, and be still: feare not, neither be faint hearted for the two tailes of these smoking firebrands, for the furious wrath of Rezin and of Aram, and of Remaliahs sonne:", "wycliffe": "And thou schalt seie to hym, Se thou, that thou be stille; nyle thou drede, and thin herte be not aferd of twei tailis of these brondis smokynge in the wraththe of woodnesse, of Rasyn, kynge of Sirie, and of the sone of Romelye.", "rotherham": "and say unto him—Take heed and keep thyself calm—do not fear, neither let thy heart be faint, because of these two fag-ends of smoking firebrands,—in spite of the glow of the anger of Rezin and Syria and the son of Remaliah.", "darby": "and thou shalt say unto him, Take heed and be quiet; fear not, and let not thy heart faint before these two ends of smoking firebrands, because of the fierce anger of Rezin and Syria, and of the son of Remaliah.", "twenty": "", "jps": "and say unto him: Keep calm, and be quiet; fear not, neither let thy heart be faint, because of these two tails of smoking firebrands, for the fierce anger of Rezin and Aram, and of the son of Remaliah.", "acv": "And say to him, Take heed, and be quiet. Fear not, nor let thy heart be faint, because of these two tails of smoking firebrands, for the fierce anger of Rezin and Syria, and of the son of Remaliah.", "anderson": "", "haweis": "", "noyes": "and say to him: Take heed, and be quiet! Fear not, neither let thy heart he faint On account of the two tails of these smoking firebrands, On account of the fierce wrath of Rezin with the Syrians, and of the son of Remaliah,", "webster": "And say to him, Take heed, and be quiet; fear not, neither be faint-hearted for the two tails of these smoking fire-brands, for the fierce anger of Rezin with Syria, and of the son of Remaliah.", "vulgate": "et dices ad eum vide ut sileas noli timere et cor tuum ne formidet a duobus caudis titionum fumigantium istorum in ira furoris Rasin et Syriae et filii Romeliae;", "brenton": "And thou shalt say to him, Take care to be quiet, and fear not, neither let thy soul be disheartened because of these two smoking firebrands: for when my fierce anger is over, I will heal again."}}, {"v": 5, "ref": "7:5", "o": "יַ֗עַן כִּֽי יָעַ֥ץ עָלֶ֛י/ךָ אֲרָ֖ם רָעָ֑ה אֶפְרַ֥יִם וּ/בֶן רְמַלְיָ֖הוּ לֵ/אמֹֽר", "en": {"kjv": "Because Syria, Ephraim, and the son of Remaliah, have taken evil counsel against thee, saying,", "web": "Because Syria, Ephraim, and the son of Remaliah, have plotted evil against you, saying,", "bsb": "For Aram, along with Ephraim and the son of Remaliah, has plotted your ruin, saying:", "asv": "Because Syria, Ephraim, and the son of Remaliah, have purposed evil against thee, saying,", "ylt": "Because that Aram counselled against thee evil, Ephraim and the son of Remaliah, saying:", "dra": "Because Syria hath taken counsel against thee, unto the evil of Ephraim and the son of Romelia, saying:", "bbe": "Because Aram has made evil designs against you, saying,", "geneva": "Because Aram hath taken wicked counsell against thee, and Ephraim, and Remaliahs sonne, saying,", "wycliffe": "For Sirie, and Effraym, and the sone of Romelie, han bigunne yuel councel ayens thee, and seien, Stie we to Juda,", "rotherham": "Because Syria, hath taken counsel against thee, for mischief,—[with] Ephraim and the son of Remaliah, saying,", "darby": "Inasmuch as Syria hath taken evil counsel against thee, Ephraim [also] and the son of Remaliah, saying,", "twenty": "", "jps": "Because Aram hath counselled evil against thee, Ephraim also, and the son of Remaliah, saying:", "acv": "Because Syria, Ephraim, and the son of Remaliah, have purposed evil against thee, saying,", "anderson": "", "haweis": "", "noyes": "Because Syria deviseth evil against thee, Ephraim and the son of Remaliah, saying,", "webster": "Because Syria, Ephraim, and the son of Remaliah, have taken evil counsel against thee, saying,", "vulgate": "eo quod consilium inierit contra te Syria malum Ephraim et filius Romeliae dicentes;", "brenton": "And as for the son of Aram, and the son of Romelias, forasmuch as they have devised an evil counsel, saying,"}}, {"v": 6, "ref": "7:6", "o": "נַעֲלֶ֤ה בִֽ/יהוּדָה֙ וּ/נְקִיצֶ֔/נָּה וְ/נַבְקִעֶ֖/נָּה אֵלֵ֑י/נוּ וְ/נַמְלִ֥יךְ מֶ֨לֶךְ֙ בְּ/תוֹכָ֔/הּ אֵ֖ת בֶּן טָֽבְאַֽל", "en": {"kjv": "Let us go up against Judah, and vex it, and let us make a breach therein for us, and set a king in the midst of it, even the son of Tabeal:", "web": "“Let’s go up against Judah, and tear it apart, and let’s divide it among ourselves, and set up a king in its midst, even the son of Tabeel.”", "bsb": "‘Let us invade Judah, terrorize it, and divide it among ourselves. Then we can install the son of Tabeal over it as king.’", "asv": "Let us go up against Judah, and vex it, and let us make a breach therein for us, and set up a king in the midst of it, even the son of Tabeel;", "ylt": "We go up into Judah, and we vex it, And we rend it unto ourselves, And we cause a king to reign in its midst--The son of Tabeal.", "dra": "Let us go up to Juda, and rouse it up, and draw it away to us, and make the son of Tabeel king in the midst thereof.", "bbe": "Let us go up against Judah, troubling her, and forcing our way into her, and let us put up a king in her, even the son of Tabeel:", "geneva": "Let vs goe vp against Iudah, and let vs waken them vp, and make a breach therein for vs, and set a King in the mids thereof, euen the sonne of Tabeal.", "wycliffe": "and reise we hym, and drawe we hym out to vs; and sette we a kyng in the myddis therof, the sone of Tabeel.", "rotherham": "Let us go up against Judah, and besiege it, and break it open, for ourselves,—and set up a king in the midst thereof, even the son of Tabeal,", "darby": "Let us go up against Judah, and harass it, and make a breach therein for us, and set up a king therein — the son of Tabeal;", "twenty": "", "jps": "Let us go up against Judah, and vex it, and let us make a breach therein for us, and set up a king in the midst of it, even the son of Tabeel;", "acv": "Let us go up against Judah, and vex it, and let us make a breach in it for us, and set up a king in the midst of it, even the son of Tabeel,", "anderson": "", "haweis": "", "noyes": "\"Let us go up against Judah, and besiege the city, And take it, And set a king in the midst of it, Even the son of Tabeal.\"", "webster": "Let us go up against Judah, and harass it, and let us make a breach therein for us, and set a king in the midst of it, [even] the son of Tabeal:", "vulgate": "ascendamus ad Iudam et suscitemus eum et avellamus eum ad nos et ponamus regem in medio eius filium Tabeel;", "brenton": "We will go up against Judea, and having conferred with them we will turn them away to our side, and we will make the son of Tabeel king of it;"}}, {"v": 7, "ref": "7:7", "o": "כֹּ֥ה אָמַ֖ר אֲדֹנָ֣/י יְהוִ֑ה לֹ֥א תָק֖וּם וְ/לֹ֥א תִֽהְיֶֽה", "en": {"kjv": "Thus saith the Lord God, It shall not stand, neither shall it come to pass.", "web": "This is what the Lord Yahweh says: “It shall not stand, neither shall it happen.”", "bsb": "But this is what the Lord GOD says: ‘It will not arise; it will not happen.", "asv": "thus saith the Lord Jehovah, It shall not stand, neither shall it come to pass.", "ylt": "Thus said the Lord Jehovah: It doth not stand, nor shall it be!", "dra": "Thus saith the Lord God: It shall not stand, and this shall not be.", "bbe": "This is the word of the Lord God: This design will not come about or be effected.", "geneva": "Thus sayth the Lord God, It shall not stand, neither shall it be.", "wycliffe": "The Lord God seith these thingis, This schal not be, and it schal not stonde;", "rotherham": "Thus, saith My Lord, Yahweh,—It shall not stand Neither shall it come to pass!", "darby": "thus saith the Lord Jehovah: It shall not stand, nor come to pass;", "twenty": "", "jps": "thus saith the L-rd GOD: it shall not stand, neither shall it come to pass.", "acv": "thus says the lord Jehovah: It shall not stand, nor shall it come to pass.", "anderson": "", "haweis": "", "noyes": "Thus saith the Lord Jehovah: \"It shall not stand, neither shall it be;", "webster": "Thus saith the Lord GOD, It shall not stand, neither shall it come to pass.", "vulgate": "haec dicit Dominus Deus non stabit et non erit istud;", "brenton": "thus saith the Lord of hosts, This counsel shall not abide, nor come to pass."}}, {"v": 8, "ref": "7:8", "o": "כִּ֣י רֹ֤אשׁ אֲרָם֙ דַּמֶּ֔שֶׂק וְ/רֹ֥אשׁ דַּמֶּ֖שֶׂק רְצִ֑ין וּ/בְ/ע֗וֹד שִׁשִּׁ֤ים וְ/חָמֵשׁ֙ שָׁנָ֔ה יֵחַ֥ת אֶפְרַ֖יִם מֵ/עָֽם", "en": {"kjv": "For the head of Syria is Damascus, and the head of Damascus is Rezin; and within threescore and five years shall Ephraim be broken, that it be not a people.", "web": "For the head of Syria is Damascus, and the head of Damascus is Rezin; and within sixty-five years Ephraim shall be broken in pieces, so that it shall not be a people;", "bsb": "For the head of Aram is Damascus, and the head of Damascus is Rezin. Within sixty-five years Ephraim will be shattered as a people.", "asv": "For the head of Syria is Damascus, and the head of Damascus is Rezin; and within threescore and five years shall Ephraim be broken in pieces, so that it shall not be a people:", "ylt": "For the head of Aram is Damascus, And the head of Damascus is Rezin, And within sixty and five years Is Ephraim broken from being a people.", "dra": "But the head of Syria is Damascus, and the head of Damascus is Rasin: and within threescore and five years, Ephraim shall cease to be a people:", "bbe": "For the head of Aram is Damascus, and the head of Damascus is Rezin (and in sixty-five years from now Ephraim will be broken, and will no longer be a people):", "geneva": "For the head of Aram is Damascus, and the head of Damascus is Rezin: and within fiue and threescore yeere, Ephraim shalbe destroyed from being a people.", "wycliffe": "but Damask schal be the heed of Sirie, and Rasyn `schal be the heed of Damask; and yit sixti yeer and fiue, and Effraym schal faile to be a puple;", "rotherham": "For, though the head of Syria is Damascus, And, the head of Damascus, is Rezin, Yet within threescore and five years more, shall Ephraim be broken that it shall not be a people;", "darby": "for the head of Syria is Damascus, and the head of Damascus is Rezin; and within sixty-five years shall Ephraim be broken, so as to be no [more a] people;", "twenty": "", "jps": "For the head of Aram is Damascus, and the head of Damascus is Rezin; and within threescore and five years shall Ephraim be broken, that it be not a people;", "acv": "For the head of Syria is Damascus, and the head of Damascus is Rezin. And within sixty-five years Ephraim shall be broken in pieces, so that is shall not be a people.", "anderson": "", "haweis": "", "noyes": "But the head of Syria shall still be Damascus, And the head of Damascus, Rezin; [And within threescore and five years shall Ephraim be broken, that he be no more a people.]", "webster": "For the head of Syria [is] Damascus, and the head of Damascus [is] Rezin; and within sixty five years shall Ephraim be broken, that it be not a people.", "vulgate": "sed caput Syriae Damascus et caput Damasci Rasin et adhuc sexaginta et quinque anni et desinet Ephraim esse populus;", "brenton": "But the head of Aram is Damascus, and the head of Damascus, Rasim; and yet within sixty and five years the kingdom of Ephraim shall cease from being a people."}}, {"v": 9, "ref": "7:9", "o": "וְ/רֹ֤אשׁ אֶפְרַ֨יִם֙ שֹׁמְר֔וֹן וְ/רֹ֥אשׁ שֹׁמְר֖וֹן בֶּן רְמַלְיָ֑הוּ אִ֚ם לֹ֣א תַאֲמִ֔ינוּ כִּ֖י לֹ֥א תֵאָמֵֽנוּ", "en": {"kjv": "And the head of Ephraim is Samaria, and the head of Samaria is Remaliah’s son. If ye will not believe, surely ye shall not be established.", "web": "and the head of Ephraim is Samaria, and the head of Samaria is Remaliah’s son. If you will not believe, surely you shall not be established.’”", "bsb": "The head of Ephraim is Samaria, and the head of Samaria is the son of Remaliah. If you do not stand firm in your faith, then you will not stand at all.’”", "asv": "and the head of Ephraim is Samaria, and the head of Samaria is Remaliah’s son. If ye will not believe, surely ye shall not be established.", "ylt": "And the head of Ephraim is Samaria, And the head of Samaria is the son of Remaliah. If ye do not give credence, Surely ye are not stedfast.'", "dra": "And the head of Ephraim is Samaria, and the head of Samaria is the son of Romelia. If you will not believe, you shall not continue.", "bbe": "And the head of Ephraim is Samaria, and the head of Samaria is Remaliah's son. If you will not have faith, your kingdom will be broken.", "geneva": "And the head of Ephraim is Samaria, and the head of Samaria is Remaliahs sonne. If ye beleeue not, surely ye shall not be established.", "wycliffe": "and Samarie shal faile to be the heed of Effraym, and the sone of Romelie `schal faile to be heed of Samarie. Forsothe if ye schulen not bileue, ye schulen not dwelle.", "rotherham": "Even though the head of Ephraim is Samaria, And, the head of Samaria, is the son of Remaliah. If ye trust not, Surely, ye cannot be trusted!", "darby": "and the head of Ephraim is Samaria, and the head of Samaria is Remaliah's son. If ye believe not, surely ye shall not be established.", "twenty": "", "jps": "And the head of Ephraim is Samaria, and the head of Samaria is Remaliah's son. If ye will not have faith, surely ye shall not be established.'", "acv": "And the head of Ephraim is Samaria, and the head of Samaria is Remaliah's son. If ye will not believe, surely ye shall not be established.", "anderson": "", "haweis": "", "noyes": "And the head of Ephraim shall still be Samaria, And the head of Samaria, the son of Remaliah. If ye will not believe, neither shall ye thrive.\"", "webster": "And the head of Ephraim [is] Samaria, and the head of Samaria [is] Remaliah's son. If ye will not believe, surely ye shall not be established.", "vulgate": "et caput Ephraim Samaria et caput Samariae filius Romeliae si non credideritis non permanebitis;", "brenton": "And the head of Ephraim is Somoron, and the head of Somoron the son of Romelias: but if ye believe not, neither will ye at all understand."}}, {"v": 10, "ref": "7:10", "o": "וַ/יּ֣וֹסֶף יְהוָ֔ה דַּבֵּ֥ר אֶל אָחָ֖ז לֵ/אמֹֽר", "en": {"kjv": "Moreover the Lord spake again unto Ahaz, saying,", "web": "Yahweh spoke again to Ahaz, saying,", "bsb": "Again the LORD spoke to Ahaz, saying,", "asv": "And Jehovah spake again unto Ahaz, saying,", "ylt": "And Jehovah addeth to speak unto Ahaz, saying:", "dra": "And the Lord spoke again to Achaz, saying:", "bbe": "And Isaiah said again to Ahaz,", "geneva": "And the Lord spake againe vnto Ahaz, saying,", "wycliffe": "And the Lord addide to speke to Achas,", "rotherham": "And again spake Yahweh unto Ahaz saying—", "darby": "And Jehovah spoke again to Ahaz, saying,", "twenty": "", "jps": "And HaShem spoke again unto Ahaz, saying:", "acv": "And Jehovah spoke again to Ahaz, saying,", "anderson": "", "haweis": "", "noyes": "Jehovah spake also again to Ahaz:", "webster": "Moreover, the LORD spoke again to Ahaz, saying,", "vulgate": "et adiecit Dominus loqui ad Ahaz dicens;", "brenton": "And the Lord again spoke to Achaz, saying,"}}, {"v": 11, "ref": "7:11", "o": "שְׁאַל לְ/ךָ֣ א֔וֹת מֵ/עִ֖ם יְהוָ֣ה אֱלֹהֶ֑י/ךָ הַעְמֵ֣ק שְׁאָ֔לָה א֖וֹ הַגְבֵּ֥הַּ לְ/מָֽעְלָ/ה", "en": {"kjv": "Ask thee a sign of the Lord thy God; ask it either in the depth, or in the height above.", "web": "“Ask a sign of Yahweh your God; ask it either in the depth, or in the height above.”", "bsb": "“Ask for a sign from the LORD your God, whether from the depths of Sheol or the heights of heaven.”", "asv": "Ask thee a sign of Jehovah thy God; ask it either in the depth, or in the height above.", "ylt": "`Ask for thee a sign from Jehovah thy God, Make deep the request, or make it high upwards.'", "dra": "Ask thee a sign of the Lord thy God, either unto the depth of hell, or unto the height above.", "bbe": "Make a request to the Lord your God for a sign, a sign in the deep places of the underworld, or in the high heavens.", "geneva": "Aske a signe for thee of the Lord thy God: aske it, either in the depth beneath or in the height aboue.", "wycliffe": "and seide, Axe thou to thee a signe of thi Lord God, in to the depthe of helle, ethir in to heiythe aboue.", "rotherham": "Ask thee a sign, of Yahweh thy God,—Go down deep for a request, Or ascend on high!", "darby": "Ask for thee a sign from Jehovah thyGod; ask for it in the deep, or in the height above.", "twenty": "", "jps": "'Ask thee a sign of HaShem thy G-d: ask it either in the depth, or in the height above.'", "acv": "Ask thee a sign of Jehovah thy God, ask it either in the depth, or in the height above.", "anderson": "", "haweis": "", "noyes": "\"Ask thee a sign of Jehovah, thy God; Ask it from below, or in the height above!\"", "webster": "Ask thee a sign from the LORD thy God; ask it either in the depth, or in the hight above.", "vulgate": "pete tibi signum a Domino Deo tuo in profundum inferni sive in excelsum supra;", "brenton": "Ask for thyself a sign of the Lord thy God, in the depth or in the height."}}, {"v": 12, "ref": "7:12", "o": "וַ/יֹּ֖אמֶר אָחָ֑ז לֹא אֶשְׁאַ֥ל וְ/לֹֽא אֲנַסֶּ֖ה אֶת יְהוָֽה", "en": {"kjv": "But Ahaz said, I will not ask, neither will I tempt the Lord.", "web": "But Ahaz said, “I will not ask, neither will I tempt Yahweh.”", "bsb": "But Ahaz replied, “I will not ask; I will not test the LORD.”", "asv": "But Ahaz said, I will not ask, neither will I tempt Jehovah.", "ylt": "And Ahaz saith, `I do not ask nor try Jehovah.'", "dra": "And Achaz said: I will not ask, and I will not tempt the Lord.", "bbe": "But Ahaz said, I will not put the Lord to the test by making such a request.", "geneva": "But Ahaz sayd, I wil not aske, neither will I tempt the Lord.", "wycliffe": "And Achas seide, Y schal not axe, and Y schal not tempte the Lord.", "rotherham": "But Ahaz said,—I will not ask Nor will I put Yahweh to the proof.", "darby": "And Ahaz said, I will not ask, and will not tempt Jehovah.", "twenty": "", "jps": "But Ahaz said: 'I will not ask, neither will I try HaShem.'", "acv": "But Ahaz said, I will not ask, nor will I test Jehovah.", "anderson": "", "haweis": "", "noyes": "And Ahaz said, I will not ask; I will not tempt Jehovah!", "webster": "But Ahaz said, I will not ask, neither will I tempt the LORD.", "vulgate": "et dixit Ahaz non petam et non temptabo Dominum;", "brenton": "And Achaz said, I will not ask, neither will I tempt the Lord."}}, {"v": 13, "ref": "7:13", "o": "וַ/יֹּ֕אמֶר שִׁמְעוּ נָ֖א בֵּ֣ית דָּוִ֑ד הַ/מְעַ֤ט מִ/כֶּם֙ הַלְא֣וֹת אֲנָשִׁ֔ים כִּ֥י תַלְא֖וּ גַּ֥ם אֶת אֱלֹהָֽ/י", "en": {"kjv": "And he said, Hear ye now, O house of David; Is it a small thing for you to weary men, but will ye weary my God also?", "web": "He said, “Listen now, house of David. Is it not enough for you to try the patience of men, that you will try the patience of my God also?", "bsb": "Then Isaiah said, “Hear now, O house of David! Is it not enough to try the patience of men? Will you try the patience of my God as well?", "asv": "And he said, Hear ye now, O house of David: Is it a small thing for you to weary men, that ye will weary my God also?", "ylt": "And he saith, `Hear, I pray you, O house of David, Is it a little thing for you to weary men, That ye weary also my God?", "dra": "And he said: Hear ye therefore, O house of David: Is it a small thing for you to be grievous to men, that you are grievous to my God also?", "bbe": "And he said, Give ear now, O family of David: is it not enough that you are driving men to disgust? will you do the same to my God?", "geneva": "Then he sayd, Heare you nowe, O house of Dauid, Is it a small thing for you to grieue men, that ye will also grieue my God?", "wycliffe": "And Ysaie seide, Therfor the hous of Dauid, here ye; whether it is litil to you to be diseseful to men, for ye ben diseseful also to my God?", "rotherham": "Then said he—Hear, I pray you, O house of David! Is it, too little, for you to weary men, that ye must weary even my God?", "darby": "And he said, Hear then, house of David: Is it a small matter for you to weary men, that ye weary also myGod?", "twenty": "", "jps": "And he said: 'Hear ye now, O house of David: Is it a small thing for you to weary men, that ye will weary my G-d also?", "acv": "And he said, Hear ye now, O house of David. Is it a small thing for you to weary men, that ye will weary my God also?", "anderson": "", "haweis": "", "noyes": "Then he said, Hear ye now, O house of David! Is it too small a thing for you to weary men, That ye should weary my God also?", "webster": "And he said, Hear ye now, O house of David? [Is it] a small thing for you to weary men, but will ye weary my God also?", "vulgate": "et dixit audite ergo domus David numquid parum vobis est molestos esse hominibus quia molesti estis et Deo meo;", "brenton": "And he said, Hear ye now, O house of David; is it a little thing for you to contend with men? and how do ye contend against the Lord?"}}, {"v": 14, "ref": "7:14", "o": "לָ֠/כֵן יִתֵּ֨ן אֲדֹנָ֥/י ה֛וּא לָ/כֶ֖ם א֑וֹת הִנֵּ֣ה הָ/עַלְמָ֗ה הָרָה֙ וְ/יֹלֶ֣דֶת בֵּ֔ן וְ/קָרָ֥את שְׁמ֖/וֹ עִמָּ֥נוּ אֵֽל", "en": {"kjv": "Therefore the Lord himself shall give you a sign; Behold, a virgin shall conceive, and bear a son, and shall call his name Immanuel.", "web": "Therefore the Lord himself will give you a sign. Behold, the virgin will conceive, and bear a son, and shall call his name Immanuel.", "bsb": "Therefore the Lord Himself will give you a sign: Behold, the virgin will be with child and will give birth to a son, and will call Him Immanuel.", "asv": "Therefore the Lord himself will give you a sign: behold, a virgin shall conceive, and bear a son, and shall call his name Immanuel.", "ylt": "Therefore the Lord Himself giveth to you a sign, Lo, the Virgin is conceiving, And is bringing forth a son, And hath called his name Immanuel,", "dra": "Therefore the Lord himself shall give you a sign. Behold a virgin shall conceive, and bear a son and his name shall be called Emmanuel.", "bbe": "For this cause the Lord himself will give you a sign; a young woman is now with child, and she will give birth to a son, and she will give him the name Immanuel.", "geneva": "Therefore the Lord himselfe will giue you a signe. Beholde, the virgine shall conceiue and beare a sonne, and she shall call his name Immanu-el.", "wycliffe": "For this thing the Lord hym silf schal yyue a signe to you. Lo! a virgyn schal conseyue, and schal bere a sone; and his name schal be clepid Emanuel.", "rotherham": "Wherefore let My Lord Himself give you a sign,—Lo! a Virgin, being with child and giving birth to a son, thou wilt call his name Immanuel.", "darby": "Therefore will the Lord himself give you a sign: Behold, the virgin shall conceive and shall bring forth a son, and call his name Immanuel.", "twenty": "", "jps": "Therefore the L-rd Himself shall give you a sign: behold, the young woman shall conceive, and bear a son, and shall call his name Immanuel.", "acv": "Therefore the Lord himself will give you a sign: Behold, a virgin shall conceive, and bear a son, and shall call his name Immanuel.", "anderson": "", "haweis": "", "noyes": "Therefore shall Jehovah himself give you a sign: Behold, the damsel shall conceive, and bear a son, And she shall call his name Immanuel.", "webster": "Therefore the Lord himself will give you a sign; Behold, a virgin shall conceive, and bear a son, and shall call his name Immanuel.", "vulgate": "propter hoc dabit Dominus ipse vobis signum ecce virgo concipiet et pariet filium et vocabitis nomen eius Emmanuhel;", "brenton": "Therefore the Lord himself shall give you a sign; behold, a virgin shall conceive in the womb, and shall bring forth a son, and thou shalt call his name Emmanuel."}}, {"v": 15, "ref": "7:15", "o": "חֶמְאָ֥ה וּ/דְבַ֖שׁ יֹאכֵ֑ל לְ/דַעְתּ֛/וֹ מָא֥וֹס בָּ/רָ֖ע וּ/בָח֥וֹר בַּ/טּֽוֹב", "en": {"kjv": "Butter and honey shall he eat, that he may know to refuse the evil, and choose the good.", "web": "He shall eat butter and honey when he knows to refuse the evil, and choose the good.", "bsb": "By the time He knows enough to reject evil and choose good, He will be eating curds and honey.", "asv": "Butter and honey shall he eat, when he knoweth to refuse the evil, and choose the good.", "ylt": "Butter and honey he doth eat, When he knoweth to refuse evil, and to fix on good.", "dra": "He shall eat butter and honey, that he may know to refuse the evil, and to choose the good.", "bbe": "Butter and honey will be his food, when he is old enough to make a decision between evil and good.", "geneva": "Butter and hony shall he eate, till he haue knowledge to refuse the euill, and to chuse the good.", "wycliffe": "He schal ete botere and hony, that he kunne repreue yuel, and cheese good.", "rotherham": "Curds and honey, shall he eat, by the time that he knoweth to refuse the bad and choose the good;", "darby": "Butter and honey shall he eat, that he may know to refuse the evil, and to choose the good.", "twenty": "", "jps": "Curd and honey shall he eat, when he knoweth to refuse the evil, and choose the good.", "acv": "Butter and honey shall he eat, when he knows to refuse the evil, and choose the good.", "anderson": "", "haweis": "", "noyes": "Milk and honey shall he eat, Until he learn to refuse the evil, and choose the good;", "webster": "Butter and honey shall he eat, that he may know to refuse the evil, and choose the good.", "vulgate": "butyrum et mel comedet ut sciat reprobare malum et eligere bonum;", "brenton": "Butter and honey shall he eat, before he knows either to prefer evil or choose the good."}}, {"v": 16, "ref": "7:16", "o": "כִּ֠י בְּ/טֶ֨רֶם יֵדַ֥ע הַ/נַּ֛עַר מָאֹ֥ס בָּ/רָ֖ע וּ/בָחֹ֣ר בַּ/טּ֑וֹב תֵּעָזֵ֤ב הָ/אֲדָמָה֙ אֲשֶׁ֣ר אַתָּ֣ה קָ֔ץ מִ/פְּנֵ֖י שְׁנֵ֥י מְלָכֶֽי/הָ", "en": {"kjv": "For before the child shall know to refuse the evil, and choose the good, the land that thou abhorrest shall be forsaken of both her kings.", "web": "For before the child knows to refuse the evil, and choose the good, the land whose two kings you abhor shall be forsaken.", "bsb": "For before the boy knows enough to reject evil and choose good, the land of the two kings you dread will be laid waste.", "asv": "For before the child shall know to refuse the evil, and choose the good, the land whose two kings thou abhorrest shall be forsaken.", "ylt": "For before the youth doth know To refuse evil, and to fix on good, Forsaken is the land thou art vexed with, because of her two kings.", "dra": "For before the child know to refuse the evil and to choose the good, the land which thou abhorrest shall be forsaken of the face of her two kings.", "bbe": "For before the child is old enough to make a decision between evil and good, the land whose two kings you are now fearing will have become waste.", "geneva": "For afore the childe shall haue knowledge to eschew the euill, and to chuse the good, the land, that thou abhorrest, shalbe forsaken of both her Kings.", "wycliffe": "For whi bifore that the child kunne repreue yuel, and chese good, the lond, which thou wlatist, schal be forsakun of the face of her twei kyngis.", "rotherham": "for before the boy knoweth to refuse the bad and choose the good, forsaken shall be the land, at which, thou, art alarmed, of the presence of both her kings.", "darby": "For before the child knoweth to refuse the evil and to choose the good, the land whose two kings thou fearest shall be forsaken.", "twenty": "", "jps": "Yea, before the child shall know to refuse the evil, and choose the good, the land whose two kings thou hast a horror of shall be forsaken.", "acv": "For before the child shall know to refuse the evil, and choose the good, the land whose two kings thou abhor shall be forsaken.", "anderson": "", "haweis": "", "noyes": "For before this child shall have learned to refuse the evil and choose the good, The land shall become desolate, On account of whose two kings thou art in terror.", "webster": "For before the child shall know to refuse the evil, and choose the good, the land that thou abhorrest shall be forsaken by both her kings.", "vulgate": "quia antequam sciat puer reprobare malum et eligere bonum derelinquetur terra quam tu detestaris a facie duum regum suorum;", "brenton": "For before the child shall know good or evil, he refuses evil, to choose the good; and the land shall be forsaken which thou art afraid of because of the two kings."}}, {"v": 17, "ref": "7:17", "o": "יָבִ֨יא יְהוָ֜ה עָלֶ֗י/ךָ וְ/עַֽל עַמְּ/ךָ֮ וְ/עַל בֵּ֣ית אָבִי/ךָ֒ יָמִים֙ אֲשֶׁ֣ר לֹא בָ֔אוּ לְ/מִ/יּ֥וֹם סוּר אֶפְרַ֖יִם מֵ/עַ֣ל יְהוּדָ֑ה אֵ֖ת מֶ֥לֶךְ אַשּֽׁוּר", "en": {"kjv": "The Lord shall bring upon thee, and upon thy people, and upon thy father’s house, days that have not come, from the day that Ephraim departed from Judah; even the king of Assyria.", "web": "Yahweh will bring on you, on your people, and on your father’s house, days that have not come, from the day that Ephraim departed from Judah; even the king of Assyria.", "bsb": "The LORD will bring on you and on your people and on the house of your father a time unlike any since the day Ephraim separated from Judah—He will bring the king of Assyria.”", "asv": "Jehovah will bring upon thee, and upon thy people, and upon thy father’s house, days that have not come, from the day that Ephraim departed from Judah—even the king of Assyria.", "ylt": "Jehovah bringeth on thee, and on thy people, And on the house of thy father, Days that have not come, Even from the day of the turning aside of Ephraim from Judah, By the king of Asshur.", "dra": "The Lord shall bring upon thee, and upon thy people, and upon the house of thy father, days that have not come since the time of the separation of Ephraim from Juda with the king of the Assyrians.", "bbe": "The Lord is about to send on you, and on your people, and on your father's house, such a time of trouble as there has not been from the days of the separating of Ephraim from Judah; even the coming of the king of Assyria.", "geneva": "The Lord shall bring vpon thee, and vpon thy people, and vpon thy fathers house (the dayes that haue not come from the day that Ephraim departed from Iudah) euen the King of Asshur.", "wycliffe": "The Lord schal brynge on thee, and on thi puple, and on the hous of thi fadir, daies that camen not fro the daies of departyng of Effraym fro Juda, with the kyng of Assiriens.", "rotherham": "Yahweh will bring upon thee and upon thy people, and upon the house of thy father, days which have not come, from the day when Ephraim departed from Judah,—even the king of Assyria.", "darby": "Jehovah will bring upon thee, and upon thy people, and upon thy father's house, days which have not come since the day when Ephraim turned away from Judah — [even] the king of Assyria.", "twenty": "", "jps": "HaShem shall bring upon thee, and upon thy people, and upon thy father's house, days that have not come, from the day that Ephraim departed from Judah; even the king of Assyria.'", "acv": "Jehovah will bring upon thee, and upon thy people, and upon thy father's house, days that have not come, from the day that Ephraim departed from Judah-even the king of Assyria.", "anderson": "", "haweis": "", "noyes": "Yet Jehovah shall bring upon thee, and upon thy people, and upon thy father’s house, Days such as have not been Since Ephraim revolted from Judah. [Even the king of Assyria.]", "webster": "The LORD will bring upon thee, and upon thy people, and upon thy father's house, days that have not come, from the day that Ephraim departed from Judah; [even] the king of Assyria.", "vulgate": "adducet Dominus super te et super populum tuum et super domum patris tui dies qui non venerunt a diebus separationis Ephraim a Iuda cum rege Assyriorum;", "brenton": "But God shall bring upon thee, and upon thy people, and upon the house of thy father, days which have never come, from the day that Ephraim took away from Juda the king of the Assyrians."}}, {"v": 18, "ref": "7:18", "o": "וְ/הָיָ֣ה בַּ/יּ֣וֹם הַ/ה֗וּא יִשְׁרֹ֤ק יְהוָה֙ לַ/זְּב֔וּב אֲשֶׁ֥ר בִּ/קְצֵ֖ה יְאֹרֵ֣י מִצְרָ֑יִם וְ/לַ֨/דְּבוֹרָ֔ה אֲשֶׁ֖ר בְּ/אֶ֥רֶץ אַשּֽׁוּר", "en": {"kjv": "And it shall come to pass in that day, that the Lord shall hiss for the fly that is in the uttermost part of the rivers of Egypt, and for the bee that is in the land of Assyria.", "web": "It will happen in that day that Yahweh will whistle for the fly that is in the uttermost part of the rivers of Egypt, and for the bee that is in the land of Assyria.", "bsb": "On that day the LORD will whistle to the flies at the farthest streams of the Nile and to the bees in the land of Assyria.", "asv": "And it shall come to pass in that day, that Jehovah will hiss for the fly that is in the uttermost part of the rivers of Egypt, and for the bee that is in the land of Assyria.", "ylt": "And it hath come to pass, in that day, Jehovah doth hiss for a fly that is in the extremity of the brooks of Egypt, And for a bee that is in the land of Asshur.", "dra": "And it shall come to pass in that day, that the Lord shall hiss for the fly, that is in the uttermost parts of the rivers of Egypt, and for the bee that is in the land of Assyria.", "bbe": "And it will be in that day that the Lord will make a piping sound for the fly which is in the end of the rivers of Egypt, and for the bee which is in the land of Assyria.", "geneva": "And in that day shall the Lord hisse for the flie that is at the vttermost part of the floods of Egypt, and for the bee which is in the lande of Asshur,", "wycliffe": "And it schal be, in that dai the Lord schal hisse to a flie, which is in the laste parte of the floodis of Egipt; and to a bee, which is in the lond of Assur;", "rotherham": "And it shall come to pass in that day that Yahweh will give a signal—To the fly that is in the uttermost part of the Nile-canals of Egypt, And to the bee that is in the land of Assyria.", "darby": "And it shall come to pass in that day, that Jehovah will hiss for the fly which is at the extremity of the streams of Egypt, and for the bee which is in the land of Assyria;", "twenty": "", "jps": "And it shall come to pass in that day, that HaShem shall hiss for the fly that is in the uttermost part of the rivers of Egypt, and for the bee that is in the land of Assyria.", "acv": "And it shall come to pass in that day, that Jehovah will whistle for the fly that is in the outermost part of the rivers of Egypt, and for the bee that is in the land of Assyria.", "anderson": "", "haweis": "", "noyes": "And it shall come to pass in that day That Jehovah shall whistle for the fly that is at the end of the streams of Egypt, And the bee that is in the land of Assyria,", "webster": "And it shall come to pass in that day, [that] the LORD will hiss for the fly that [is] in the uttermost part of the rivers of Egypt, and for the bee that [is] in the land of Assyria.", "vulgate": "et erit in die illa sibilabit Dominus muscae quae est in extremo fluminum Aegypti et api quae est in terra Assur;", "brenton": "And it shall come to pass in that day that the Lord shall hiss for the flies, which insect shall rule over a part of the river of Egypt, and for the bee which is in the land of the Assyrians."}}, {"v": 19, "ref": "7:19", "o": "וּ/בָ֨אוּ וְ/נָח֤וּ כֻלָּ/ם֙ בְּ/נַחֲלֵ֣י הַ/בַּתּ֔וֹת וּ/בִ/נְקִיקֵ֖י הַ/סְּלָעִ֑ים וּ/בְ/כֹל֙ הַ/נַּ֣עֲצוּצִ֔ים וּ/בְ/כֹ֖ל הַ/נַּהֲלֹלִֽים", "en": {"kjv": "And they shall come, and shall rest all of them in the desolate valleys, and in the holes of the rocks, and upon all thorns, and upon all bushes.", "web": "They shall come, and shall all rest in the desolate valleys, in the clefts of the rocks, on all thorn hedges, and on all pastures.", "bsb": "And they will all come and settle in the steep ravines and clefts of the rocks, in all the thornbushes and watering holes.", "asv": "And they shall come, and shall rest all of them in the desolate valleys, and in the clefts of the rocks, and upon all thorn-hedges, and upon all pastures.", "ylt": "And they have come, and rested all of them in the desolate valleys, And in holes of the rocks, and on all the thorns, And on all the commendable things.", "dra": "And they shall come, and shall all of them rest in the torrents of the valleys, and in the holes of the rocks, and upon all places set with shrubs, and in all hollow places.", "bbe": "And they will come, covering all the waste valleys, and the holes of the rocks, and the thorns, and all the watering-places.", "geneva": "And they shall come and shall light all in the desolate valleys, and in the holes of the rockes, and vpon all thorny places, and vpon all bushy places.", "wycliffe": "and `alle so schulen come, and schulen reste in the strondis of valeis, and in caues of stoonis, and in alle places of buyschis, and in alle hoolis.", "rotherham": "And they shall all of them come and settle down—In the desolate torrent-valleys, And in the rents of the crags,—And on all the thorn-bushes, And on all the pastures,", "darby": "and they shall come and settle all of them in the desolate valleys, and in the holes of the rocks, and on all thorn-bushes, and on all the pastures.", "twenty": "", "jps": "And they shall come, and shall rest all of them in the rugged valleys, and in the holes of the rocks, and upon all thorns, and upon all brambles.", "acv": "And they shall come, and shall rest all of them in the desolate valleys, and in the clefts of the rocks, and upon all thorn-hedges, and upon all pastures.", "anderson": "", "haweis": "", "noyes": "And they shall come, and light all of them In the desolate valleys, and fissures of the rocks, And upon all hedges, and upon all pastures.", "webster": "And they shall come, and shall rest all of them in the desolate valleys, and in the holes of the rocks, and upon all thorns, and upon all bushes.", "vulgate": "et venient et requiescent omnes in torrentibus vallium et cavernis petrarum et in omnibus frutectis et in universis foraminibus;", "brenton": "And they all shall enter into the clefts of the land, and into the holes of the rocks, and into the caves, and into every ravine."}}, {"v": 20, "ref": "7:20", "o": "בַּ/יּ֣וֹם הַ/ה֡וּא יְגַלַּ֣ח אֲדֹנָ/י֩ בְּ/תַ֨עַר הַ/שְּׂכִירָ֜ה בְּ/עֶבְרֵ֤י נָהָר֙ בְּ/מֶ֣לֶךְ אַשּׁ֔וּר אֶת הָ/רֹ֖אשׁ וְ/שַׂ֣עַר הָ/רַגְלָ֑יִם וְ/גַ֥ם אֶת הַ/זָּקָ֖ן תִּסְפֶּֽה", "en": {"kjv": "In the same day shall the Lord shave with a razor that is hired, namely, by them beyond the river, by the king of Assyria, the head, and the hair of the feet: and it shall also consume the beard.", "web": "In that day the Lord will shave with a razor that is hired in the parts beyond the River, even with the king of Assyria, the head and the hair of the feet; and it shall also consume the beard.", "bsb": "On that day the Lord will use a razor hired from beyond the Euphrates—the king of Assyria—to shave your head and the hair of your legs, and to remove your beard as well.", "asv": "In that day will the Lord shave with a razor that is hired in the parts beyond the River, even with the king of Assyria, the head and the hair of the feet; and it shall also consume the beard.", "ylt": "In that day doth the Lord shave, By a razor that is hired beyond the river, By the king of Asshur, The head, and the hair of the feet, Yea, also the beard it consumeth.", "dra": "In that day the Lord shall shave with a razor that is hired by them that are beyond the river, by the king of the Assyrians, the head and the hairs of the feet, and the whole beard.", "bbe": "In that day will the Lord take away the hair of the head and of the feet, as well as the hair of the face, with a blade got for a price from the other side of the River; even with the king of Assyria.", "geneva": "In that day shall the Lord shaue with a rasor that is hired, euen by them beyond the Riuer, by the King of Asshur, the head and the heare of the feete, and it shall consume the beard.", "wycliffe": "And in that dai the Lord schal schaue with a scharp rasour in these men, that ben biyendis the flood, in the kyng of Assiriens, the heed, and heeris of the feet, and al the beerd.", "rotherham": "In that day, will My Lord shave, with a hired razor, even with them of the lands over the River Euphrates, with the king of Assyria, the head and the hair of the feet,—yea, even the beard, will it sweep off.", "darby": "In that day will the Lord, with a razor which is hired beyond the river, with the king of Assyria, shave the head and the hair of the feet, yea, the beard also will it take away.", "twenty": "", "jps": "In that day shall the L-rd shave with a razor that is hired in the parts beyond the River, even with the king of Assyria, the head and the hair of the feet; and it shall also sweep away the beard.", "acv": "In that day the Lord will shave with a razor what is hired in the parts beyond the River, even with the king of Assyria, the head and the hair of the feet, and it shall also consume the beard.", "anderson": "", "haweis": "", "noyes": "In that day shall Jehovah shave, with a razor hired beyond the river, [with the king of Assyria,] The head, and the hair of the feet; Yea, even the beard shall he take away.", "webster": "In the same day will the Lord shave with a razor that is hired, [namely], by them beyond the river, by the king of Assyria, the head, and the hair of the feet: and it shall also consume the beard.", "vulgate": "in die illa radet Dominus in novacula conducta in his qui trans Flumen sunt in rege Assyriorum caput et pilos pedum et barbam universam;", "brenton": "In that day the Lord shall shave with the hired razor of the king of Assyria beyond the river the head, and the hairs of the feet, and will remove the beard."}}, {"v": 21, "ref": "7:21", "o": "וְ/הָיָ֖ה בַּ/יּ֣וֹם הַ/ה֑וּא יְחַיֶּה אִ֛ישׁ עֶגְלַ֥ת בָּקָ֖ר וּ/שְׁתֵּי צֹֽאן", "en": {"kjv": "And it shall come to pass in that day, that a man shall nourish a young cow, and two sheep;", "web": "It shall happen in that day that a man shall keep alive a young cow, and two sheep;", "bsb": "On that day a man will raise a young cow and two sheep,", "asv": "And it shall come to pass in that day, that a man shall keep alive a young cow, and two sheep;", "ylt": "And it hath come to pass, in that day, A man keepeth alive a heifer of the herd, And two of the flock,", "dra": "And it shall come to pass in that day, that a man shall nourish a young cow, and two sheep.", "bbe": "And it will be in that day that a man will give food to a young cow and two sheep;", "geneva": "And in the same day shall a man nourish a yong kow, and two sheepe.", "wycliffe": "And it schal be, in that day a man schal nurische a cow of oxis, and twei scheep,", "rotherham": "And it shall come to pass in that day, that a man shall keep alive a young cow and two sheep.", "darby": "And it shall come to pass in that day, [that] a man shall nourish a young cow and two sheep,", "twenty": "", "jps": "And it shall come to pass in that day, that a man shall rear a young cow, and two sheep;", "acv": "And it shall come to pass in that day, that a man shall keep alive a young cow and two sheep.", "anderson": "", "haweis": "", "noyes": "And it shall come to pass in that day, That a man shall keep a young cow, and two sheep;", "webster": "And it shall come to pass in that day, [that] a man shall nourish a young cow, and two sheep;", "vulgate": "et erit in die illa nutriet homo vaccam boum et duas oves;", "brenton": "And it shall come to pass in that day, that a man shall rear a heifer, and two sheep."}}, {"v": 22, "ref": "7:22", "o": "וְ/הָיָ֗ה מֵ/רֹ֛ב עֲשׂ֥וֹת חָלָ֖ב יֹאכַ֣ל חֶמְאָ֑ה כִּֽי חֶמְאָ֤ה וּ/דְבַשׁ֙ יֹאכֵ֔ל כָּל הַ/נּוֹתָ֖ר בְּ/קֶ֥רֶב הָ/אָֽרֶץ", "en": {"kjv": "And it shall come to pass, for the abundance of milk that they shall give he shall eat butter: for butter and honey shall every one eat that is left in the land.", "web": "and it shall happen, that because of the abundance of milk which they shall give he shall eat butter: for everyone will eat butter and honey that is left in the midst of the land.", "bsb": "and from the abundance of milk they give, he will eat curds; for all who remain in the land will eat curds and honey.", "asv": "and it shall come to pass, that because of the abundance of milk which they shall give he shall eat butter: for butter and honey shall every one eat that is left in the midst of the land.", "ylt": "And it hath come to pass, From the abundance of the yielding of milk he eateth butter, For butter and honey doth every one eat Who is left in the heart of the land.", "dra": "And for the abundance of milk he shall eat butter: for butter and honey shall every one eat that shall be left in the midst of the land.", "bbe": "And they will give so much milk that he will be able to have butter for his food: for butter and honey will be the food of all who are still living in the land.", "geneva": "And for the abundance of milke, that they shall giue, hee shall eate butter: for butter and hony shall euery one eate, which is left within the land.", "wycliffe": "and for the plentee of mylk he schal ete botere; for whi ech man that schal be left in the myddis of the lond, schal ete boter and hony.", "rotherham": "Yea it shall come to pass for the abundance of the yield of milk, that he shall eat curds,—for, curds and honey, shall every one eat that is left in the midst of the land.", "darby": "and it shall come to pass, from the abundance of milk they shall give, [that] he shall eat butter; for every one that remaineth in the midst of the land shall eat butter and honey.", "twenty": "", "jps": "and it shall come to pass, for the abundance of milk that they shall give, he shall eat curd; for curd and honey shall every one eat that is left in the midst of the land.", "acv": "And it shall come to pass, that because of the abundance of milk which they shall give he shall eat butter. For everyone who is left in the midst of the land shall eat butter and honey.", "anderson": "", "haweis": "", "noyes": "And for the abundance of milk which they produce, shall he eat cheese; For milk and honey shall all eat Who are left in the land,", "webster": "And it shall come to pass, for the abundance of milk [that] they shall give, he shall eat butter: for butter and honey shall every one eat that is left in the land.", "vulgate": "et prae ubertate lactis comedet butyrum butyrum enim et mel manducabit omnis qui relictus fuerit in medio terrae;", "brenton": "And it shall come to pass from their drinking an abundance of milk, that every one that is left on the land shall eat butter and honey."}}, {"v": 23, "ref": "7:23", "o": "וְ/הָיָה֙ בַּ/יּ֣וֹם הַ/ה֔וּא יִֽהְיֶ֣ה כָל מָק֗וֹם אֲשֶׁ֧ר יִֽהְיֶה שָּׁ֛ם אֶ֥לֶף גֶּ֖פֶן בְּ/אֶ֣לֶף כָּ֑סֶף לַ/שָּׁמִ֥יר וְ/לַ/שַּׁ֖יִת יִֽהְיֶֽה", "en": {"kjv": "And it shall come to pass in that day, that every place shall be, where there were a thousand vines at a thousand silverlings, it shall even be for briers and thorns.", "web": "It will happen in that day that every place where there were a thousand vines at a thousand silver shekels, shall be for briers and thorns.", "bsb": "And on that day, in every place that had a thousand vines worth a thousand shekels of silver, only briers and thorns will be found.", "asv": "And it shall come to pass in that day, that every place, where there were a thousand vines at a thousand silverlings, shall be for briers and thorns.", "ylt": "And it hath come to pass, in that day, Every place where there are a thousand vines, At a thousand silverlings, Is for briers and for thorns.", "dra": "And it shall come to pass in that day, that every place where there were a thousand vines, at a thousand pieces of silver, shall become thorns and briers.", "bbe": "And it will be in that day that in every place where before there were a thousand vines valued at a thousand shekels of silver, there will be nothing but blackberries and thorns.", "geneva": "And at the same day euery place, wherein shalbe a thousand vines, shalbe at a thousand pieces of siluer: so it shalbe for the briers and for the thornes.", "wycliffe": "And it schal be, in that dai ech place where a thousand vyneris schulen be worth a thousynde platis of siluer, and schulen be in to thornes and breeris,", "rotherham": "And it shall some to pass in that day, that, every place wherein there used to be a thousand vines at a thousand pieces of silver,—yea, even for briars and thorns, shall it be.", "darby": "And it shall come to pass in that day, [that] every place, where there were a thousand vines at a thousand silver pieces, shall become briars and thorns:", "twenty": "", "jps": "And it shall come to pass in that day, that every place, where there were a thousand vines at a thousand silverlings, shall even be for briers and thorns.", "acv": "And it shall come to pass in that day, that every place where there were a thousand vines at a thousand silver coins, shall be for briers and thorns.", "anderson": "", "haweis": "", "noyes": "And it shall come to pass in that day, That every place where stood a thousand vines, worth a thousand shekels of silver, Shall be covered with briers and thorns.", "webster": "And it shall come to pass in that day, [that] every place shall be, where there were a thousand vines at a thousand pieces of silver, it shall [even] be for briers and thorns.", "vulgate": "et erit in die illa omnis locus ubi fuerint mille vites mille argenteis et in spinas et in vepres erunt;", "brenton": "And it shall come to pass in that day, for every place where there shall be a thousand vines at a thousand shekels, they shall become barren land and thorns."}}, {"v": 24, "ref": "7:24", "o": "בַּ/חִצִּ֥ים וּ/בַ/קֶּ֖שֶׁת יָ֣בוֹא שָׁ֑מָּ/ה כִּי שָׁמִ֥יר וָ/שַׁ֖יִת תִּֽהְיֶ֥ה כָל הָ/אָֽרֶץ", "en": {"kjv": "With arrows and with bows shall men come thither; because all the land shall become briers and thorns.", "web": "People will go there with arrows and with bow, because all the land will be briers and thorns.", "bsb": "Men will go there with bow and arrow, for the land will be covered with briers and thorns.", "asv": "With arrows and with bow shall one come thither, because all the land shall be briers and thorns.", "ylt": "With arrows and with bow he cometh thither, Because all the land is brier and thorn.", "dra": "With arrows and with bows they shall go in thither: for briers and thorns shall be in all the land.", "bbe": "Men will come there with bows and arrows, because all the land will be full of blackberries and thorns.", "geneva": "With arrowes and with bowe shall one come thither: because all the land shall be briers and thornes.", "wycliffe": "men schulen entre thidur with bouwis and arowis; for whi breris and thornes schulen be in al the lond.", "rotherham": "With arrows and with a bow, shall one come in thither,—for briars and thorns, shall be all the land.", "darby": "with arrows and with the bow shall they come thither, for the whole land shall become briars and thorns.", "twenty": "", "jps": "With arrows and with bow shall one come thither; because all the land shall become briers and thorns.", "acv": "Men shall come there with arrows and with bow, because all the land shall be briers and thorns.", "anderson": "", "haweis": "", "noyes": "With arrows and with bows shall men go thither; For all the land shall become briers and thorns.", "webster": "With arrows and with bows shall [men] come thither; because all the land shall become briers and thorns.", "vulgate": "cum sagittis et arcu ingredientur illuc vepres enim et spinae erunt in universa terra;", "brenton": "Men shall enter thither with arrow and bow; for all the land shall be barren ground and thorns."}}, {"v": 25, "ref": "7:25", "o": "וְ/כֹ֣ל הֶ/הָרִ֗ים אֲשֶׁ֤ר בַּ/מַּעְדֵּר֙ יֵעָ֣דֵר֔וּ/ן לֹֽא תָב֣וֹא שָׁ֔מָּ/ה יִרְאַ֖ת שָׁמִ֣יר וָ/שָׁ֑יִת וְ/הָיָה֙ לְ/מִשְׁלַ֣ח שׁ֔וֹר וּ/לְ/מִרְמַ֖ס שֶֽׂה", "en": {"kjv": "And on all hills that shall be digged with the mattock, there shall not come thither the fear of briers and thorns: but it shall be for the sending forth of oxen, and for the treading of lesser cattle.", "web": "All the hills that were cultivated with the hoe, you shall not come there for fear of briers and thorns; but it shall be for the sending out of oxen, and for the treading of sheep.”", "bsb": "For fear of the briers and thorns, you will no longer traverse the hills once tilled by the hoe; they will become places for oxen to graze and sheep to trample.", "asv": "And all the hills that were digged with the mattock, thou shalt not come thither for fear of briers and thorns; but it shall be for the sending forth of oxen, and for the treading of sheep.", "ylt": "And all the hills that with a mattock are kept in order, Thither cometh not the fear of brier and thorn, And it hath been for the sending forth of ox, And for the treading of sheep!'", "dra": "And as for the hills that shall be raked with a rake, the fear of thorns and briers shall not come thither, but they shall be for the ox to feed on, and the lesser cattle to tread upon.", "bbe": "And they will send out the oxen and the sheep on all the hills which before were worked with the spade, ... fear of blackberries and thorns.", "geneva": "But on all the mountaines, which shalbe digged with the mattocke, there shall not come thither the feare of briers and thornes: but they shalbe for the sending out of bullocks, and for the treading of sheepe.", "wycliffe": "And alle hillis that schulen be purgid with a sarpe, the drede of thornes and of breris schal not come thidir; and it schal be in to lesewe of oxen, and in to treding of scheep.", "rotherham": "But all the hills which, with the hoe, can be weeded,—there shall not come thither, the fear of briars and thorns,—but it shall be for the sending forth of oxen, and for the tread of lesser cattle.", "darby": "And all mountains that have been dug up with the hoe — thither will they not come, from fear of briars and thorns; and they shall be for the sending forth of oxen, and for the treading of small cattle.", "twenty": "", "jps": "And all the hills that were digged with the mattock, thou shalt not come thither for fear of briers and thorns, but it shall be for the sending forth of oxen, and for the treading of sheep.", "acv": "And all the hills that were dug with the mattock, thou shall not come there for fear of briers and thorns, but it shall be for the sending forth of oxen, and for the treading of sheep.", "anderson": "", "haweis": "", "noyes": "All the hills that were digged with the mattock Shall no one approach through fear of briers and thorns; They shall be for the pasturage of oxen, And the trampling of sheep.", "webster": "And [on] all hills that shall be digged with the mattock, there shall not come thither the fear of briers and thorns: but it shall be for the sending forth of oxen, and for the treading of lesser cattle.", "vulgate": "et omnes montes qui in sarculo sarientur non veniet illuc terror spinarum et veprium et erit in pascua bovis et in conculcationem pecoris;", "brenton": "And every mountain shall be certainly ploughed: there shall no fear come thither: for there shall be from among the barren ground and thorns that whereon cattle shall feed and oxen shall tread."}}]}, {"c": 8, "verses": [{"v": 1, "ref": "8:1", "o": "וַ/יֹּ֤אמֶר יְהוָה֙ אֵלַ֔/י קַח לְ/ךָ֖ גִּלָּי֣וֹן גָּד֑וֹל וּ/כְתֹ֤ב עָלָי/ו֙ בְּ/חֶ֣רֶט אֱנ֔וֹשׁ לְ/מַהֵ֥ר שָׁלָ֖ל חָ֥שׁ בַּֽז", "en": {"kjv": "Moreover the Lord said unto me, Take thee a great roll, and write in it with a man’s pen concerning Maher–shalal–hash–baz.", "web": "Yahweh said to me, “Take a large tablet, and write on it with a man’s pen, ‘For Maher Shalal Hash Baz’;", "bsb": "Then the LORD said to me, “Take a large scroll and write on it with an ordinary stylus: Maher-shalal-hash-baz.", "asv": "And Jehovah said unto me, Take thee a great tablet, and write upon it with the pen of a man, For Maher-shalal-hash-baz;", "ylt": "And Jehovah saith unto me, `Take to thee a great tablet, and write upon it with a graving tool of man, To haste spoil, enjoy prey.'", "dra": "And the Lord said to me: Take thee a great book, and write in it with a man's pen. Take away the spoils with speed, quickly take the prey.", "bbe": "And the Lord said to me, Take a great writing-board, and on it put down in common letters, Maher-shalal-hash-baz;", "geneva": "Moreover, the Lord sayd vnto me, Take thee a great roll, and write in it with a mans penne, Make speede to the spoyle: haste to the praye.", "wycliffe": "And the Lord seide to me, Take to thee a greet book, and write ther ynne with the poyntil of man, Swiftli drawe thou awei spuylis, take thou prey soone.", "rotherham": "And Yahweh said unto me: Take thee a large tablet,—and write thereon in plain characters, To Maher-shalal-hash-baz. [\"Speed-spoil-hurry-prey\".]", "darby": "And Jehovah said to me, Take thee a great tablet, and write thereon with a man's style, concerning Maher-shalal-hash-baz.", "twenty": "", "jps": "And HaShem said unto me: 'Take thee a great tablet, and write upon it in common script: The spoil speedeth, the prey hasteth;", "acv": "And Jehovah said to me, Take thee a great tablet, and write upon it with the pen of a man, For Maher-shalal-hash-baz.", "anderson": "", "haweis": "", "noyes": "And Jehovah said to me, Take thee a great tablet, and with a man’s writing-instrument write on it, Hasteth-the-prey, Speedeth-the-spoil.", "webster": "Moreover, the LORD said to me, Take thee a great roll, and write in it with a man's pen concerning Maher-shalal-hash-baz.", "vulgate": "et dixit Dominus ad me sume tibi librum grandem et scribe in eo stilo hominis Velociter spolia detrahe Cito praedare;", "brenton": "And the Lord said to me, Take to thyself a volume of a great new book, and write in it with a man's pen concerning the making a rapid plunder of spoils; for it is near at hand."}}, {"v": 2, "ref": "8:2", "o": "וְ/אָעִ֣ידָה לִּ֔/י עֵדִ֖ים נֶאֱמָנִ֑ים אֵ֚ת אוּרִיָּ֣ה הַ/כֹּהֵ֔ן וְ/אֶת זְכַרְיָ֖הוּ בֶּ֥ן יְבֶרֶכְיָֽהוּ", "en": {"kjv": "And I took unto me faithful witnesses to record, Uriah the priest, and Zechariah the son of Jeberechiah.", "web": "and I will take for myself faithful witnesses to testify: Uriah the priest, and Zechariah the son of Jeberechiah.”", "bsb": "And I will appoint for Myself trustworthy witnesses—Uriah the priest and Zechariah son of Jeberekiah.”", "asv": "and I will take unto me faithful witnesses to record, Uriah the priest, and Zechariah the son of Jeberechiah.", "ylt": "And I cause faithful witnesses to testify to me, Uriah the priest, and Zechariah son of Jeberechiah.", "dra": "And I took unto me faithful witnesses, Urias the priest, and Zacharias the son of Barachias.", "bbe": "And take true witnesses to the writing, Uriah the priest, and Zechariah, the son of Jeberechiah.", "geneva": "Then I tooke vnto me faithfull witnesses to recorde, Vriah the Priest, and Zechariah the sonne of Ieberechiah.", "wycliffe": "And Y yaf to me faithful witnessis, Vrie, the prest, and Sacarie, the sone of Barachie.", "rotherham": "That I may take in attestation, faithful witnesses,—even Uriah the priest, and Zechariah son of Jeberechiah.", "darby": "And I took unto me to witness, sure witnesses, Urijah the priest, and Zechariah the son of Jeberechiah.", "twenty": "", "jps": "and I will take unto Me faithful witnesses to record, Uriah the priest, and Zechariah the son of Jeberechiah.'", "acv": "And I will take to me faithful witnesses to record, Uriah the priest, and Zechariah the son of Jeberechiah.", "anderson": "", "haweis": "", "noyes": "And I took with me faithful witnesses, Uriah the priest, and Zechariah, the son of Berechiah.", "webster": "And I took to me faithful witnesses to record, Uriah the priest, and Zechariah the son of Jeberechiah.", "vulgate": "et adhibui mihi testes fideles Uriam sacerdotem et Zacchariam filium Barachiae;", "brenton": "And make me witnesses of faithful men, Urias, and Zacharias the son of Barachias."}}, {"v": 3, "ref": "8:3", "o": "וָ/אֶקְרַב֙ אֶל הַ/נְּבִיאָ֔ה וַ/תַּ֖הַר וַ/תֵּ֣לֶד בֵּ֑ן וַ/יֹּ֤אמֶר יְהוָה֙ אֵלַ֔/י קְרָ֣א שְׁמ֔/וֹ מַהֵ֥ר שָׁלָ֖ל חָ֥שׁ בַּֽז", "en": {"kjv": "And I went unto the prophetess; and she conceived, and bare a son. Then said the Lord to me, Call his name Maher–shalal–hash–baz.", "web": "I went to the prophetess, and she conceived, and bore a son. Then Yahweh said to me, “Call his name ‘Maher Shalal Hash Baz.’", "bsb": "And I had relations with the prophetess, and she conceived and gave birth to a son. The LORD said to me, “Name him Maher-shalal-hash-baz.", "asv": "And I went unto the prophetess; and she conceived, and bare a son. Then said Jehovah unto me, Call his name Maher-shalal-hash-baz.", "ylt": "And I draw near unto the prophetess, and she conceiveth, and beareth a son; and Jehovah saith unto me, `Call his name Maher-shalal-hash-baz,", "dra": "And I went to the prophetess, and she conceived, and bore a son. And the Lord said to me: Call his name, Hasten to take away the spoils: Make hast to take away the prey.", "bbe": "And I went in to my wife, and she became with child, and gave birth to a son. Then the Lord said to me, Give him the name Maher-shalal-hash-baz,", "geneva": "After, I came vnto the Prophetesse, which conceiued, and bare a sonne. Then sayd the Lord to me, Call his name, Mahershalalhash-baz.", "wycliffe": "And Y neiyede to the profetesse; and sche conseyuede, and childide a sone. And the Lord seide to me, Clepe thou his name Haste thou to drawe awei spuylis, haaste thou for to take prey.", "rotherham": "Then approached I unto the prophetess, and she conceived and bare a son,—and Yahweh said unto me, Call his name Maher-shalal-hash-baz.", "darby": "And I came near to the prophetess, and she conceived and bore a son; and Jehovah said unto me, Call his name, Maher-shalal-hash-baz.", "twenty": "", "jps": "And I went unto the prophetess; and she conceived, and bore a son. Then said HaShem unto me: 'Call his name Maher-shalal-hashbaz.", "acv": "And I went to the prophetess, and she conceived, and bore a son. Then Jehovah said to me, Call his name Maher-shalal-hash-baz.", "anderson": "", "haweis": "", "noyes": "I went in to the prophetess, and she conceived and bore a son. Then said Jehovah to me, Call his name, Hasteth-the-prey, Speedeth-the-spoil.", "webster": "And I went to the prophetess; and she conceived, and bore a son. Then said the LORD to me, Call his name Maher-shalal-hash-baz.", "vulgate": "et accessi ad prophetissam et concepit et peperit filium et dixit Dominus ad me voca nomen eius Adcelera spolia detrahere Festina praedari;", "brenton": "And I went in to the prophetess; and she conceived, and bore a son. And the Lord said to me, Call his name, Spoil quickly, plunder speedily."}}, {"v": 4, "ref": "8:4", "o": "כִּ֗י בְּ/טֶ֨רֶם֙ יֵדַ֣ע הַ/נַּ֔עַר קְרֹ֖א אָבִ֣/י וְ/אִמִּ֑/י יִשָּׂ֣א אֶת חֵ֣יל דַּמֶּ֗שֶׂק וְ/אֵת֙ שְׁלַ֣ל שֹׁמְר֔וֹן לִ/פְנֵ֖י מֶ֥לֶךְ אַשּֽׁוּר", "en": {"kjv": "For before the child shall have knowledge to cry, My father, and my mother, the riches of Damascus and the spoil of Samaria shall be taken away before the king of Assyria.", "web": "For before the child knows how to say, ‘My father,’ and, ‘My mother,’ the riches of Damascus and the plunder of Samaria will be carried away by the king of Assyria.”", "bsb": "For before the boy knows how to cry ‘Father’ or ‘Mother,’ the wealth of Damascus and the plunder of Samaria will be carried off by the king of Assyria.”", "asv": "For before the child shall have knowledge to cry, My father, and, My mother, the riches of Damascus and the spoil of Samaria shall be carried away before the king of Assyria.", "ylt": "for before the youth doth know to cry, My father, and My mother, one taketh away the wealth of Damascus and the spoil of Samaria, before the king of Asshur.'", "dra": "For before the child know to call his father and his mother, the strength of Damascus, and the spoils of Samaria shall be taken away before the king of the Assyrians.", "bbe": "For before the child is able to say, Father, or, Mother, the wealth of Damascus and the goods of Samaria will be taken away by the king of Assyria.", "geneva": "For before the childe shall haue knowledge to crye, My father, and my mother, he shall take away the riches of Damascus and the spoyle of Samaria, before the King of Asshur.", "wycliffe": "For whi bifor that the child kan clepe his fadir and his modir, the strengthe of Damask schal be doon awei, and the spuylis of Samarie, bifor the kyng of Assiriens.", "rotherham": "For before the boy shall have knowledge to cry, My father! and, My mother! the riches of Damascus and the spoil of Samaria shall be carried away before the king of Assyria.", "darby": "For before the lad knoweth to cry, My father! and, My mother! the riches of Damascus and the spoil of Samaria shall be taken away before the king of Assyria.", "twenty": "", "jps": "For before the child shall have knowledge to cry: My father, and: My mother, the riches of Damascus and the spoil of Samaria shall be carried away before the king of Assyria.'", "acv": "For before the child shall have knowledge to cry, My father, and, My mother, the riches of Damascus and the spoil of Samaria shall be carried away before the king of Assyria.", "anderson": "", "haweis": "", "noyes": "For before the child shall learn to say, My father, and My mother, the riches of Damascus and the spoil of Samaria shall be borne away before the king of Assyria.", "webster": "For before the child shall have knowledge to cry, My father, and my mother, the riches of Damascus and the spoil of Samaria shall be taken away before the king of Assyria.", "vulgate": "quia antequam sciat puer vocare patrem suum et matrem suam auferetur fortitudo Damasci et spolia Samariae coram rege Assyriorum;", "brenton": "For before the child shall know how to call his father or his mother, one shall take the power of Damascus and the spoils of Samaria before the king of the Assyrians."}}, {"v": 5, "ref": "8:5", "o": "וַ/יֹּ֣סֶף יְהוָ֔ה דַּבֵּ֥ר אֵלַ֛/י ע֖וֹד לֵ/אמֹֽר", "en": {"kjv": "The Lord spake also unto me again, saying,", "web": "Yahweh spoke to me yet again, saying,", "bsb": "And the LORD spoke to me further:", "asv": "And Jehovah spake unto me yet again, saying,", "ylt": "And Jehovah addeth to speak unto me again, saying:", "dra": "And the Lord spoke to me again, saying:", "bbe": "And the Lord said again to me,", "geneva": "And the Lord spake yet againe vnto me, saying,", "wycliffe": "And the Lord addide to speke yit to me, and he seide,", "rotherham": "And again Yahweh spake unto me yet further saying:", "darby": "And Jehovah spoke again to me, saying,", "twenty": "", "jps": "And HaShem spoke unto me yet again, saying:", "acv": "And Jehovah spoke to me yet again, saying,", "anderson": "", "haweis": "", "noyes": "Moreover, Jehovah spake to me again, saying:", "webster": "The LORD spoke also to me again, saying,", "vulgate": "et adiecit Dominus loqui ad me adhuc dicens;", "brenton": "And the Lord spoke to me yet again, saying,"}}, {"v": 6, "ref": "8:6", "o": "יַ֗עַן כִּ֤י מָאַס֙ הָ/עָ֣ם הַ/זֶּ֔ה אֵ֚ת מֵ֣י הַ/שִּׁלֹ֔חַ הַ/הֹלְכִ֖ים לְ/אַ֑ט וּ/מְשׂ֥וֹשׂ אֶת רְצִ֖ין וּ/בֶן רְמַלְיָֽהוּ", "en": {"kjv": "Forasmuch as this people refuseth the waters of Shiloah that go softly, and rejoice in Rezin and Remaliah’s son;", "web": "“Because this people have refused the waters of Shiloah that go softly, and rejoice in Rezin and Remaliah’s son;", "bsb": "“Because this people has rejected the gently flowing waters of Shiloah and rejoiced in Rezin and the son of Remaliah,", "asv": "Forasmuch as this people have refused the waters of Shiloah that go softly, and rejoice in Rezin and Remaliah’s son;", "ylt": "`Because that this people hath refused The waters of Shiloah that go softly, And is rejoicing with Rezin and the son of Remaliah,", "dra": "Forasmuch as this people hath cast away the waters of Siloe, that go with silence, and hath rather taken Rasin, and the son of Romelia:", "bbe": "Because this people will have nothing to do with the softly-flowing waters of Shiloah, and have fear of Rezin and Remaliah's son;", "geneva": "Because this people hath refused the waters of Shiloah that runne softly, and reioyce with Rezin, and the sonne of Remaliah,", "wycliffe": "For that thing that this puple hath caste awei the watris of Siloe, that goen with silence, and hath take more Rasyn, and the sone of Romelie, for this thing lo!", "rotherham": "Because this people hath refused the waters of Shiloah which flow softly,—and are rejoicing with Rezin and the son of Remaliah,", "darby": "Forasmuch as this people refuseth the waters of Shiloah which flow softly, and rejoiceth in Rezin and in the son of Remaliah,", "twenty": "", "jps": "Forasmuch as this people hath refused the waters of Shiloah that go softly, and rejoiceth with Rezin and Remaliah's son;", "acv": "Inasmuch as this people have refused the waters of Shiloah that go softly, and rejoice in Rezin and Remaliah's son,", "anderson": "", "haweis": "", "noyes": "Because this people despiseth The soft-flowing waters of Siloah, And rejoiceth in Rezin, and the son of Remaliah,", "webster": "Forasmuch as this people refuseth the waters of Shiloah that flow gently, and rejoice in Rezin and Remaliah's son;", "vulgate": "pro eo quod abiecit populus iste aquas Siloae quae vadunt cum silentio et adsumpsit magis Rasin et filium Romeliae;", "brenton": "Because this people chooses not the water of Siloam that goes softly, but wills to have Rassin, and the son of Romelias to be king over you;"}}, {"v": 7, "ref": "8:7", "o": "וְ/לָ/כֵ֡ן הִנֵּ֣ה אֲדֹנָ/י֩ מַעֲלֶ֨ה עֲלֵי/הֶ֜ם אֶת מֵ֣י הַ/נָּהָ֗ר הָ/עֲצוּמִים֙ וְ/הָ֣/רַבִּ֔ים אֶת מֶ֥לֶךְ אַשּׁ֖וּר וְ/אֶת כָּל כְּבוֹד֑/וֹ וְ/עָלָה֙ עַל כָּל אֲפִיקָ֔י/ו וְ/הָלַ֖ךְ עַל כָּל גְּדוֹתָֽי/ו", "en": {"kjv": "Now therefore, behold, the Lord bringeth up upon them the waters of the river, strong and many, even the king of Assyria, and all his glory: and he shall come up over all his channels, and go over all his banks:", "web": "now therefore, behold, the Lord brings upon them the mighty flood waters of the River: the king of Assyria and all his glory. It will come up over all its channels, and go over all its banks.", "bsb": "the Lord will surely bring against them the mighty floodwaters of the Euphrates— the king of Assyria and all his pomp. It will overflow its channels and overrun its banks.", "asv": "now therefore, behold, the Lord bringeth up upon them the waters of the River, strong and many, even the king of Assyria and all his glory: and it shall come up over all its channels, and go over all its banks;", "ylt": "Therefore, lo, the Lord is bringing up on them, The waters of the river, the mighty and the great, (The king of Asshur, and all his glory,) And it hath gone up over all its streams, And hath gone on over all its banks.", "dra": "Therefore behold the Lord will bring upon them the waters of the river strong and many, the king of the Assyrians, and all his glory: and he shall come up over all his channels, and shall overflow all his banks.", "bbe": "For this cause the Lord is sending on them the waters of the River, deep and strong, even the king of Assyria and all his glory: and it will come up through all its streams, overflowing all its edges:", "geneva": "Nowe therefore, beholde, the Lord bringeth vp vpon them the waters of the Riuer mightie and great, euen the King of Asshur with all his glory, and he shall come vp vpon all their riuers, and goe ouer all their banks,", "wycliffe": "the Lord schal brynge on hem the stronge and many watris of the flood, the king of Assiriens, and al his glorie; and he schal stiye on alle the stremes therof, and he schal flowe on alle the ryueris therof.", "rotherham": "now therefore, lo! the Lord is about to bring up against them the waters, strong and many, of the River [=\"Euphrates\"], even the king of Assyria and all his glory,—and he shall rise over all his channels, and flow over all his banks;", "darby": "therefore behold, the Lord will bring up upon them the waters of the river, strong and many, the king of Assyria and all his glory; and he shall mount up over all his channels, and go over all his banks:", "twenty": "", "jps": "Now therefore, behold, the L-rd bringeth up upon them the waters of the River, mighty and many, even the king of Assyria and all his glory; and he shall come up over all his channels, and go over all his banks;", "acv": "now therefore, behold, the Lord brings up upon them the waters of the River, strong and many, even the king of Assyria and all his glory. And it shall come up over all its channels, and go over all its banks,", "anderson": "", "haweis": "", "noyes": "Therefore, behold, the Lord bringeth upon them the strong and mighty waters of the river; [The king of Assyria and all his glory.] He shall rise above all his channels, And go over all his banks.", "webster": "Now therefore, behold, the Lord bringeth up upon them the waters of the river, strong and many, [even] the king of Assyria, and all his glory: and he shall come up over all its channels, and go over all its banks:", "vulgate": "propter hoc ecce Dominus adducet super eos aquas Fluminis fortes et multas regem Assyriorum et omnem gloriam eius et ascendet super omnes rivos eius et fluet super universas ripas eius;", "brenton": "therefore, behold, the Lord brings up upon you the water of the river, strong and abundant, even the king of the Assyrians, and his glory: and he shall come up over every valley of yours, and shall walk over every wall of yours:"}}, {"v": 8, "ref": "8:8", "o": "וְ/חָלַ֤ף בִּֽ/יהוּדָה֙ שָׁטַ֣ף וְ/עָבַ֔ר עַד צַוָּ֖אר יַגִּ֑יעַ וְ/הָיָה֙ מֻטּ֣וֹת כְּנָפָ֔י/ו מְלֹ֥א רֹֽחַב אַרְצְ/ךָ֖ עִמָּ֥נוּ אֵֽל", "en": {"kjv": "And he shall pass through Judah; he shall overflow and go over, he shall reach even to the neck; and the stretching out of his wings shall fill the breadth of thy land, O Immanuel.", "web": "It will sweep onward into Judah. It will overflow and pass through; it will reach even to the neck; and the stretching out of its wings will fill the breadth of your land, Immanuel.", "bsb": "It will pour into Judah, swirling and sweeping over it, reaching up to the neck; its spreading streams will cover your entire land, O Immanuel!", "asv": "and it shall sweep onward into Judah; it shall overflow and pass through; it shall reach even to the neck; and the stretching out of its wings shall fill the breadth of thy land, O Immanuel.", "ylt": "And it hath passed on into Judah, It hath overflown and passed over, Unto the neck it cometh, And the stretching out of its wings Hath been the fulness of the breadth of thy land, O Emmanu-El!", "dra": "And shall pass through Juda, overflowing, and going over shall reach even to the neck. And the stretching out of his wings shall fill the breadth of thy, land, O Emmanuel.", "bbe": "And it will come on into Judah; rushing on and overflowing, till the waters are up to the neck; *** and his outstretched wings will be covering the land from side to side: for God is with us.", "geneva": "And shall breake into Iudah, and shall ouerflowe and passe through, and shall come vp to the necke, and the stretching out of his wings shall fill the breadth of thy land, O Immanu-el.", "wycliffe": "And he schal go flowynge bi Juda, and he schal passe til to the necke, and schal come; and the spredyng forth of hise wyngis schal be, and schal fille the breede of thi lond, thou Emanuel.", "rotherham": "and roll on throughout Judah—overflow and pass along, till unto the neck, he shall reach,—and it shall be, that, the stretching out of his wings, shall fill the breadth of thy land, O Immanuel!", "darby": "and he shall pass through Judah; he shall overflow it and go further, he shall reach even to the neck; and the stretching out of his wings shall fill the breadth of thy land, O Immanuel!", "twenty": "", "jps": "And he shall sweep through Judah overflowing as he passeth through he shall reach even to the neck; and the stretching out of his wings shall fill the breadth of thy land, O Immanuel.", "acv": "and it shall sweep onward into Judah. It shall overflow and pass through; it shall reach even to the neck. And the stretching out of its wings shall fill the breadth of thy land, O Immanuel.", "anderson": "", "haweis": "", "noyes": "And he shall pass through Judah, overflowing and spreading; Even to the neck shall he reach, And his stretched-out wings shall fill the whole breadth of thy land, O Immanuel!", "webster": "And he shall pass through Judah; he shall overflow and go over, he shall reach [even] to the neck; and the extension of his wings shall fill the breadth of thy land, O Immanuel.", "vulgate": "et ibit per Iudam inundans et transiens usque ad collum veniet et erit extensio alarum eius implens latitudinem terrae tuae o Emmanuhel;", "brenton": "and he shall take away from Juda every man who shall be able to lift up his head, and every one able to accomplish anything; and his camp shall fill the breadth of thy land, O God with us."}}, {"v": 9, "ref": "8:9", "o": "רֹ֤עוּ עַמִּים֙ וָ/חֹ֔תּוּ וְ/הַֽאֲזִ֔ינוּ כֹּ֖ל מֶרְחַקֵּי אָ֑רֶץ הִתְאַזְּר֣וּ וָ/חֹ֔תּוּ הִֽתְאַזְּר֖וּ וָ/חֹֽתּוּ", "en": {"kjv": "Associate yourselves, O ye people, and ye shall be broken in pieces; and give ear, all ye of far countries: gird yourselves, and ye shall be broken in pieces; gird yourselves, and ye shall be broken in pieces.", "web": "Make an uproar, you peoples, and be broken in pieces! Listen, all you from far countries: dress for battle, and be shattered! Dress for battle, and be shattered!", "bsb": "Huddle together, O peoples, and be shattered; pay attention, all you distant lands; prepare for battle, and be shattered; prepare for battle, and be shattered!", "asv": "Make an uproar, O ye peoples, and be broken in pieces; and give ear, all ye of far countries: gird yourselves, and be broken in pieces; gird yourselves, and be broken in pieces.", "ylt": "Be friends, O nations, and be broken, And give ear, all ye far off ones of earth, Gird yourselves, and be broken, Gird yourselves, and be broken.", "dra": "Gather yourselves together, O ye people, and be overcome, and give ear, all ye lands afar off: strengthen yourselves, and be overcome, gird yourselves, and be overcome.", "bbe": "Have knowledge, O peoples, and be in fear; give ear, all you far-off parts of the earth:", "geneva": "Gather together on heapes, O ye people, and ye shalbe broken in pieces, and hearken all ye of farre countreys: gird your selues, and you shalbe broken in pieces: gird your selues, and you shalbe broken in pieces.", "wycliffe": "Puplis, be ye gaderid togidere, and be ye ouercomun; and alle londis afer, here ye. Be ye coumfortid, and be ye ouercomun; gird ye you, and be ye ouercomun;", "rotherham": "Rage, O ye peoples,—and be overthrown, And give ear, all ye distant parts of the earth,—Gird yourselves and be overthrown, Gird yourselves, and be overthrown:", "darby": "Rage, ye peoples, and be broken in pieces! And give ear, all ye distant parts of the earth: Gird yourselves, and be broken in pieces; gird yourselves, and be broken in pieces!", "twenty": "", "jps": "Make an uproar, O ye peoples, and ye shall be broken in pieces; and give ear, all ye of far countries; gird yourselves, and ye shall be broken in pieces; gird yourselves, and ye shall be broken in pieces.", "acv": "Make an uproar, O ye peoples, and be broken in pieces. And give ear, all ye of far countries. Gird yourselves, and be broken in pieces. Gird yourselves, and be broken in pieces.", "anderson": "", "haweis": "", "noyes": "Rage, ye nations, and despair! Give ear, all ye distant parts of the earth! Gird yourselves, and despair! Gird yourselves, and despair!", "webster": "Associate yourselves, O ye people, and ye shall be broken in pieces; and give ear, all ye of far countries: gird yourselves, and ye shall be broken in pieces; gird yourselves, and ye shall be broken in pieces.", "vulgate": "congregamini populi et vincimini et audite universae procul terrae confortamini et vincimini accingite vos et vincimini;", "brenton": "Know, ye Gentiles, and be conquered; hearken ye, even to the extremity of the earth: be conquered, after ye strengthened yourselves; for even if ye should again strengthen yourselves, ye shall again be conquered."}}, {"v": 10, "ref": "8:10", "o": "עֻ֥צוּ עֵצָ֖ה וְ/תֻפָ֑ר דַּבְּר֤וּ דָבָר֙ וְ/לֹ֣א יָק֔וּם כִּ֥י עִמָּ֖/נוּ אֵֽל", "en": {"kjv": "Take counsel together, and it shall come to nought; speak the word, and it shall not stand: for God is with us.", "web": "Take counsel together, and it will be brought to nothing; speak the word, and it will not stand: for God is with us.”", "bsb": "Devise a plan, but it will be thwarted; state a proposal, but it will not happen. For God is with us.”", "asv": "Take counsel together, and it shall be brought to nought; speak the word, and it shall not stand: for God is with us.", "ylt": "Take counsel, and it is broken, Speak a word, and it doth not stand, Because of Emmanu-El!'", "dra": "Take counsel together, and it shall be defeated: speak a word, and it shall not be done: because God is with us.", "bbe": "Let your designs be formed, and they will come to nothing; give your orders, and they will not be effected: for God is with us.", "geneva": "Take counsell together, yet it shall be brought to nought: pronounce a decree, yet shall it not stand: for God is with vs.", "wycliffe": "take ye councel, and it schal be destried; speke ye a word, and it schal not be doon, for God is with vs.", "rotherham": "Determine a plan,—and it shall be frustrated,—Speak a word, and it shall not stand, For With-us-is-GOD!", "darby": "Settle a plan, and it shall come to nought; speak a word, and it shall not stand: forGod is with us.", "twenty": "", "jps": "Take counsel together, and it shall be brought to nought; speak the word, and it shall not stand; for G-d is with us.", "acv": "Take counsel together, and it shall be brought to nothing. Speak the word, and it shall not stand, for God is with us.", "anderson": "", "haweis": "", "noyes": "Form your plan, and it shall come to naught; Give the command, and it shall not stand; For God is with us.", "webster": "Take counsel together, and it shall come to naught; speak the word, and it shall not stand: for God [is] with us.", "vulgate": "inite consilium et dissipabitur loquimini verbum et non fiet quia nobiscum Deus;", "brenton": "And whatsoever counsel ye shall take, the Lord shall bring it to nought; and whatsoever word ye shall speak, it shall not stand among you: for God is with us."}}, {"v": 11, "ref": "8:11", "o": "כִּי֩ כֹ֨ה אָמַ֧ר יְהוָ֛ה אֵלַ֖/י כְּ/חֶזְקַ֣ת הַ/יָּ֑ד וְ/יִסְּרֵ֕/נִי מִ/לֶּ֛כֶת בְּ/דֶ֥רֶךְ הָֽ/עָם הַ/זֶּ֖ה לֵ/אמֹֽר", "en": {"kjv": "For the Lord spake thus to me with a strong hand, and instructed me that I should not walk in the way of this people, saying,", "web": "For Yahweh spoke thus to me with a strong hand, and instructed me not to walk in the way of this people, saying,", "bsb": "For this is what the LORD has spoken to me with a strong hand, instructing me not to walk in the way of this people:", "asv": "For Jehovah spake thus to me with a strong hand, and instructed me not to walk in the way of this people, saying,", "ylt": "For thus hath Jehovah spoken unto me with strength of hand, and instructeth me against walking in the way of this people, saying,", "dra": "For thus saith the Lord to me: As he hath taught me, with a strong arm, that I should not walk in the way of this people, saying:", "bbe": "For the Lord, controlling me with a strong hand, gave me orders not to go in the way of this people, saying,", "geneva": "For the Lord spake thus to me in taking of mine hand, and taught me, that I should not walke in the way of this people, saying,", "wycliffe": "For whi the Lord seith these thingis to me, as he tauyte me in a stronge hond, that Y schulde not go in to the weie of this puple,", "rotherham": "For, thus, spake Yahweh unto me like a firm grasp of the hand,—when he admonished me, not to walk in the way of this people, saying:", "darby": "For Jehovah spoke thus to me with a strong hand, and he instructed me not to walk in the way of this people, saying,", "twenty": "", "jps": "For HaShem spoke thus to me with a strong hand, admonishing me that I should not walk in the way of this people, saying:", "acv": "For Jehovah spoke thus to me with a strong hand, and instructed me not to walk in the way of this people, saying,", "anderson": "", "haweis": "", "noyes": "For thus spake Jehovah to me with a strong hand, Instructing me not to walk in the way of this people:", "webster": "For the LORD spoke thus to me with a strong hand, and instructed me that I should not walk in the way of this people, saying,", "vulgate": "haec enim ait Dominus ad me sicut in forti manu erudivit me ne irem in via populi huius dicens;", "brenton": "Thus saith the Lord, With a strong hand they revolt from the course of the way of this people, saying,"}}, {"v": 12, "ref": "8:12", "o": "לֹא תֹאמְר֣וּ/ן קֶ֔שֶׁר לְ/כֹ֧ל אֲשֶׁר יֹאמַ֛ר הָ/עָ֥ם הַ/זֶּ֖ה קָ֑שֶׁר וְ/אֶת מוֹרָא֥/וֹ לֹֽא תִֽירְא֖וּ וְ/לֹ֥א תַעֲרִֽיצוּ", "en": {"kjv": "Say ye not, A confederacy, to all them to whom this people shall say, A confederacy; neither fear ye their fear, nor be afraid.", "web": "“Don’t say, ‘A conspiracy!’ concerning all about which this people say, ‘A conspiracy!’ neither fear their threats, nor be terrorized.", "bsb": "“Do not call conspiracy everything these people regard as conspiracy. Do not fear what they fear; do not live in dread.", "asv": "Say ye not, A conspiracy, concerning all whereof this people shall say, A conspiracy; neither fear ye their fear, nor be in dread thereof.", "ylt": "`Ye do not say, A confederacy, To all to whom this people saith, A confederacy, And its fear ye do not fear, Nor declare fearful.", "dra": "Say ye not: A conspiracy: for all that this people speaketh, is a conspiracy: neither fear ye their fear, nor be afraid.", "bbe": "Do not say, It is holy, about everything of which this people says, It is holy; and do not be in fear of what they go in fear of.", "geneva": "Say ye not, A confederacie to all them, to whome this people sayth a confederacie, neither feare you their feare, nor be afrayd of them.", "wycliffe": "and seide, Seie ye not, It is sweryng togidere, for whi alle thingis which this puple spekith is sweryng togidere; and drede ye not the ferdfulnesse therof, nether be ye aferd.", "rotherham": "Ye shall not say—A confederacy! of everything of which this people may say. A confederacy! And their fear, shall ye not fear or regard as awful:", "darby": "Ye shall not say, Conspiracy, of everything of which this people saith, Conspiracy; and fear ye not their fear, and be not in dread.", "twenty": "", "jps": "'Say ye not: A conspiracy, concerning all whereof this people do say: A conspiracy; neither fear ye their fear, nor account it dreadful.", "acv": "Say ye not, A conspiracy, concerning all of which this people shall say, A conspiracy, nor fear ye their fear, nor be in dread of it.", "anderson": "", "haweis": "", "noyes": "Call not everything a confederacy which this people calleth a confederacy; Fear ye not what they fear, Neither be afraid!", "webster": "Say ye not, A confederacy, to all [them to] whom this people shall say, A confederacy; neither fear ye their fear, nor be afraid.", "vulgate": "non dicatis coniuratio omnia enim quae loquitur populus iste coniuratio est et timorem eius ne timeatis neque paveatis;", "brenton": "Let them not say, It is hard, for whatsoever this people says, is hard: but fear not ye their fear, neither be dismayed."}}, {"v": 13, "ref": "8:13", "o": "אֶת יְהוָ֥ה צְבָא֖וֹת אֹת֣/וֹ תַקְדִּ֑ישׁוּ וְ/ה֥וּא מוֹרַאֲ/כֶ֖ם וְ/ה֥וּא מַֽעֲרִֽצְ/כֶֽם", "en": {"kjv": "Sanctify the Lord of hosts himself; and let him be your fear, and let him be your dread.", "web": "Yahweh of Armies is who you must respect as holy. He is the one you must fear. He is the one you must dread.", "bsb": "The LORD of Hosts is the One you shall regard as holy. Only He should be feared; only He should be dreaded.", "asv": "Jehovah of hosts, him shall ye sanctify; and let him be your fear, and let him be your dread.", "ylt": "Jehovah of Hosts--Him ye do sanctify, And He is your Fear, and He your Dread,", "dra": "Sanctify the Lord of hosts himself: and let him be your fear, and let him be your dread.", "bbe": "But let the Lord of armies be holy to you, and go in fear of him, giving honour to him.", "geneva": "Sanctifie the Lord of hostes, and let him be your feare, and let him be your dread,", "wycliffe": "Halowe ye the Lord hym silf of oostis; and he schal be youre inward drede, and he schal be youre ferdfulnesse, and he schal be to you in to halewyng.", "rotherham": "Yahweh of hosts, him, shall ye hallow,—And let, him, be your fear, and let, him inspire you with awe;", "darby": "Jehovah of hosts, him shall ye sanctify; and let him be your fear, and let him be your dread.", "twenty": "", "jps": "HaShem of hosts, Him shall ye sanctify; and let Him be your fear, and let Him be your dread.", "acv": "Jehovah of hosts, him ye shall sanctify, and let him be your fear, and let him be your dread.", "anderson": "", "haweis": "", "noyes": "Jehovah of hosts, sanctify ye him; Let him be your fear, and let him be your dread!", "webster": "Sanctify the LORD of hosts himself; and [let] him [be] your fear, and [let] him [be] your dread.", "vulgate": "Dominum exercituum ipsum sanctificate ipse pavor vester et ipse terror vester;", "brenton": "Sanctify ye the Lord himself; and he shall be thy fear."}}, {"v": 14, "ref": "8:14", "o": "וְ/הָיָ֖ה לְ/מִקְדָּ֑שׁ וּ/לְ/אֶ֣בֶן נֶ֠גֶף וּ/לְ/צ֨וּר מִכְשׁ֜וֹל לִ/שְׁנֵ֨י בָתֵּ֤י יִשְׂרָאֵל֙ לְ/פַ֣ח וּ/לְ/מוֹקֵ֔שׁ לְ/יוֹשֵׁ֖ב יְרוּשָׁלִָֽם", "en": {"kjv": "And he shall be for a sanctuary; but for a stone of stumbling and for a rock of offence to both the houses of Israel, for a gin and for a snare to the inhabitants of Jerusalem.", "web": "He will be a sanctuary, but for both houses of Israel, he will be a trap and a snare for the inhabitants of Jerusalem.", "bsb": "And He will be a sanctuary— but to both houses of Israel a stone of stumbling and a rock of offense, to the dwellers of Jerusalem a trap and a snare.", "asv": "And he shall be for a sanctuary; but for a stone of stumbling and for a rock of offence to both the houses of Israel, for a gin and for a snare to the inhabitants of Jerusalem.", "ylt": "And He hath been for a sanctuary, And for a stone of stumbling, and for a rock of falling, To the two houses of Israel, For a gin and for a snare to the inhabitants of Jerusalem.", "dra": "And he shall be a sanctification to you. But for a stone of stumbling, and for a rock of offence to the two houses of Israel, for a snare and a ruin to the inhabitants of Jerusalem.", "bbe": "And he will be for a holy place: but for a stone of falling and a rock of trouble to the two houses of Israel, and to the men of Jerusalem, for a net in which they may be taken.", "geneva": "And he shalbe as a Sanctuarie: but as a stumbling stone, and as a rocke to fall vpon, to both the houses of Israel, and as a snare and as a net to the inhabitants of Ierusalem.", "wycliffe": "Forsothe he schal be in to a stoon of hirtyng, and in to a stoon of sclaundre, to tweyne housis of Israel; in to a snare, and in to fallyng, to hem that dwellen in Jerusalem.", "rotherham": "So shall he become a hallowed asylum,—But a stone to strike against, and a rock to stumble over unto both houses of Israel A trap and a snare to the dweller in Jerusalem;", "darby": "And he will be for a sanctuary; and for a stone of stumbling, and for a rock of offence to both the houses of Israel, for a gin and for a snare to the inhabitants of Jerusalem.", "twenty": "", "jps": "And He shall be for a sanctuary; but for a stone of stumbling and for a rock of offence to both the houses of Israel, for a gin and for a snare to the inhabitants of Jerusalem.", "acv": "And he shall be for a sanctuary, but for a stone of stumbling and for a rock of offense to both the houses of Israel, for a net and for a snare to the inhabitants of Jerusalem.", "anderson": "", "haweis": "", "noyes": "And he shall be to you a sanctuary; But a stone of stumbling, and a rock to strike against, To the two houses of Israel, A trap and a snare to the inhabitants of Jerusalem.", "webster": "And he will be for a sanctuary; but for a stone of stumbling and for a rock of offense to both the houses of Israel, for a trap and for a snare to the inhabitants of Jerusalem.", "vulgate": "et erit vobis in sanctificationem in lapidem autem offensionis et in petram scandali duabus domibus Israhel in laqueum et in ruinam habitantibus Hierusalem;", "brenton": "And if thou shalt trust in him, he shall be to thee for a sanctuary; and ye shall not come against him as against a stumbling-stone, neither as against the falling of a rock: but the houses of Jacob are in a snare, and the dwellers in Jerusalem in a pit."}}, {"v": 15, "ref": "8:15", "o": "וְ/כָ֥שְׁלוּ בָ֖/ם רַבִּ֑ים וְ/נָפְל֣וּ וְ/נִשְׁבָּ֔רוּ וְ/נוֹקְשׁ֖וּ וְ/נִלְכָּֽדוּ", "en": {"kjv": "And many among them shall stumble, and fall, and be broken, and be snared, and be taken.", "web": "Many will stumble over it, fall, be broken, be snared, and be captured.”", "bsb": "Many will stumble over these; they will fall and be broken; they will be ensnared and captured.”", "asv": "And many shall stumble thereon, and fall, and be broken, and be snared, and be taken.", "ylt": "And many among them have stumbled and fallen, And been broken, and snared, and captured.", "dra": "And very many of them shall stumble and fall, and shall be broken in pieces, and shall be snared, and taken.", "bbe": "And numbers of them, falling on the stone, will be broken, and will be taken in the net.", "geneva": "And many among them shall stumble, and shall fall and shalbe broken and shalbe snared and shalbe taken.", "wycliffe": "And ful many of hem schulen offende, and schulen falle, and thei schulen be al to-brokun, and thei schulen be boundun, and schulen be takun.", "rotherham": "And many, shall stumble among them,—and fall and be torn, and snared, and captured.", "darby": "And many among them shall stumble, and fall, and be broken, and snared, and taken.", "twenty": "", "jps": "And many among them shall stumble, and fall, and be broken, and be snared, and be taken.'", "acv": "And many shall stumble on it, and fall, and be broken, and be snared, and be taken.", "anderson": "", "haweis": "", "noyes": "And many among them shall stumble; They shall fall, and be broken; They shall be ensnared and taken.", "webster": "And many among them shall stumble, and fall, and be broken, and be insnared, and be taken.", "vulgate": "et offendent ex eis plurimi et cadent et conterentur et inretientur et capientur;", "brenton": "Therefore many among them shall be weak, and fall, and be crushed; and they shall draw nigh, and men shall be taken securely."}}, {"v": 16, "ref": "8:16", "o": "צ֖וֹר תְּעוּדָ֑ה חֲת֥וֹם תּוֹרָ֖ה בְּ/לִמֻּדָֽ/י", "en": {"kjv": "Bind up the testimony, seal the law among my disciples.", "web": "Wrap up the testimony. Seal the law among my disciples.", "bsb": "Bind up the testimony and seal the law among my disciples.", "asv": "Bind thou up the testimony, seal the law among my disciples.", "ylt": "Bind up the testimony, Seal the law among My disciples.", "dra": "Bind up the testimony, seal the law among my disciples.", "bbe": "Let my teaching be kept secret: and my words be given to my disciples only.", "geneva": "Binde vp the testimonie: seale vp the Law among my disciples.", "wycliffe": "Bynde thou witnessyng, mark thou the lawe in my disciplis.", "rotherham": "Bind thou up the testimony,—Seal the instruction amongst my disciples.", "darby": "Bind up the testimony, seal the law among my disciples.", "twenty": "", "jps": "'Bind up the testimony, seal the instruction among My disciples.'", "acv": "Bind thou up the testimony. Seal the law among my disciples.", "anderson": "", "haweis": "", "noyes": "Bind up the revelation, Seal the word, with my disciples!", "webster": "Bind up the testimony, seal the law among my disciples.", "vulgate": "liga testimonium signa legem in discipulis meis;", "brenton": "Then shall those who seal themselves that they may not learn the law be made manifest."}}, {"v": 17, "ref": "8:17", "o": "וְ/חִכִּ֨יתִי֙ לַ/יהוָ֔ה הַ/מַּסְתִּ֥יר פָּנָ֖י/ו מִ/בֵּ֣ית יַעֲקֹ֑ב וְ/קִוֵּ֖יתִֽי לֽ/וֹ", "en": {"kjv": "And I will wait upon the Lord, that hideth his face from the house of Jacob, and I will look for him.", "web": "I will wait for Yahweh, who hides his face from the house of Jacob, and I will look for him.", "bsb": "I will wait for the LORD, who is hiding His face from the house of Jacob. I will put my trust in Him.", "asv": "And I will wait for Jehovah, that hideth his face from the house of Jacob, and I will look for him.", "ylt": "And I have waited for Jehovah, Who is hiding His face from the house of Jacob, And I have looked for Him.", "dra": "And I will wait for the Lord, who hath hid his face from the house of Jacob, and I will look for him.", "bbe": "And I will be waiting for the Lord, whose face is veiled from the house of Jacob, and I will be looking for him.", "geneva": "Therefore I will waite vpon the Lord that hath hid his face from the house of Iaakob, and I wil looke for him.", "wycliffe": "Y schal abide the Lord, that hath hid his face fro the hous of Jacob, and Y schal abide hym.", "rotherham": "I will therefore long for Yahweh, Who is hiding his face from the house of Jacob,—And will wait, for him.", "darby": "And I will wait for Jehovah, who hideth his face from the house of Jacob; and I will look for him.", "twenty": "", "jps": "And I will wait for HaShem, that hideth His face from the house of Jacob, and I will look for Him.", "acv": "And I will wait for Jehovah, who hides his face from the house of Jacob, and I will be a man who has trusted in him.", "anderson": "", "haweis": "", "noyes": "I will, therefore, wait for Jehovah, Who now hideth his face from the house of Jacob; Yet will I look for him.", "webster": "And I will wait upon the LORD, that hideth his face from the house of Jacob, and I will look for him.", "vulgate": "et expectabo Dominum qui abscondit faciem suam a domo Iacob et praestolabor eum;", "brenton": "And one shall say, I will wait for God, who has turned away his face from the house of Jacob, and I will trust in him."}}, {"v": 18, "ref": "8:18", "o": "הִנֵּ֣ה אָנֹכִ֗י וְ/הַ/יְלָדִים֙ אֲשֶׁ֣ר נָֽתַן לִ֣/י יְהוָ֔ה לְ/אֹת֥וֹת וּ/לְ/מוֹפְתִ֖ים בְּ/יִשְׂרָאֵ֑ל מֵ/עִם֙ יְהוָ֣ה צְבָא֔וֹת הַ/שֹּׁכֵ֖ן בְּ/הַ֥ר צִיּֽוֹן", "en": {"kjv": "Behold, I and the children whom the Lord hath given me are for signs and for wonders in Israel from the Lord of hosts, which dwelleth in mount Zion.", "web": "Behold, I and the children whom Yahweh has given me are for signs and for wonders in Israel from Yahweh of Armies, who dwells in Mount Zion.", "bsb": "Here am I, and the children the LORD has given me as signs and symbols in Israel from the LORD of Hosts, who dwells on Mount Zion.", "asv": "Behold, I and the children whom Jehovah hath given me are for signs and for wonders in Israel from Jehovah of hosts, who dwelleth in mount Zion.", "ylt": "Lo, I, and the children whom Jehovah hath given to me, Are for signs and for wonders in Israel, From Jehovah of Hosts, who is dwelling in Mount Zion.", "dra": "Behold I and my children, whom the Lord hath given me for a sign, and for a wonder in Israel from the Lord of hosts, who dwelleth in mount Sion.", "bbe": "See, I and the children whom the Lord has given me, are for signs and for wonders in Israel from the Lord of armies, whose resting-place is in Mount Zion.", "geneva": "Beholde, I and the children whome the Lord hath giuen me, are as signes and as wonders in Israel, by the Lord of hostes, which dwelleth in mount Zion.", "wycliffe": "Lo! Y and my children, whiche the Lord yaf to me in to a signe, and greet wondur to Israel, of the Lord of oostis that dwellith in the hil of Sion.", "rotherham": "Lo! I and the children whom Yahweh hath given me, are for signs and for wonders in Israel,—from Yahweh of hosts, who is making his habitation in Mount Zion.", "darby": "Behold, I and the children that Jehovah hath given me are for signs and for wonders in Israel, from Jehovah of hosts, who dwelleth in mount Zion.", "twenty": "", "jps": "Behold, I and the children whom HaShem hath given me shall be for signs and for wonders in Israel from HaShem of hosts, who dwelleth in mount Zion.", "acv": "Behold, I and the children whom Jehovah has given me are for signs and for wonders in Israel from Jehovah of hosts, who dwells in mount Zion.", "anderson": "", "haweis": "", "noyes": "Behold, I, and the children which Jehovah hath given me, Are signs and tokens in Israel From Jehovah of hosts, who dwelleth upon mount Zion.", "webster": "Behold, I and the children whom the LORD hath given me [are] for signs and for wonders in Israel from the LORD of hosts, who dwelleth in mount Zion.", "vulgate": "ecce ego et pueri quos mihi dedit Dominus in signum et in portentum Israhelis a Domino exercituum qui habitat in monte Sion;", "brenton": "Behold I and the children which God has given me: and they shall be for signs and wonders in the house of Israel from the Lord of hosts, who dwells in mount Sion."}}, {"v": 19, "ref": "8:19", "o": "וְ/כִֽי יֹאמְר֣וּ אֲלֵי/כֶ֗ם דִּרְשׁ֤וּ אֶל הָ/אֹבוֹת֙ וְ/אֶל הַ/יִּדְּעֹנִ֔ים הַֽ/מְצַפְצְפִ֖ים וְ/הַ/מַּהְגִּ֑ים הֲ/לוֹא עַם֙ אֶל אֱלֹהָ֣י/ו יִדְרֹ֔שׁ בְּעַ֥ד הַ/חַיִּ֖ים אֶל הַ/מֵּתִֽים", "en": {"kjv": "And when they shall say unto you, Seek unto them that have familiar spirits, and unto wizards that peep, and that mutter: should not a people seek unto their God? for the living to the dead?", "web": "When they tell you, “Consult with those who have familiar spirits and with the wizards, who chirp and who mutter:” shouldn’t a people consult with their God? Should they consult the dead on behalf of the living?", "bsb": "When men tell you to consult the spirits of the dead and the spiritists who whisper and mutter, shouldn’t a people consult their God instead? Why consult the dead on behalf of the living?", "asv": "And when they shall say unto you, Seek unto them that have familiar spirits and unto the wizards, that chirp and that mutter: should not a people seek unto their God? on behalf of the living should they seek unto the dead?", "ylt": "And when they say unto you, `Seek unto those having familiar spirits, And unto wizards, who chatter and mutter, Doth not a people seek unto its God? --For the living unto the dead!", "dra": "And when they shall say to you: Seek of pythons, and of diviners, who mutter in their enchantments: should not the people seek of their God, for the living of the dead?", "bbe": "And when they say to you, Make request for us to those who have control of spirits, and to those wise in secret arts, who make hollow bird-like sounds; is it not right for a people to make request to their gods, to make request for the living to the dead?", "geneva": "And when they shall say vnto you, Enquire at them that haue a spirit of diuination, and at the soothsayers, which whisper and murmure, Should not a people enquire at their God? from the liuing to the dead?", "wycliffe": "And whanne thei seien to you, Axe ye of coniureris, and of false dyuynouris, that gnasten in her enchauntyngis, whether the puple schal not axe of her God a reuelacioun for quyke men and deed?", "rotherham": "But, when they say unto you—Seek ye unto the necromancers and unto the wizards, who chirp, and who mutter, Should not a people seek, unto its God? In behalf of the living, [should it seek] unto the dead?", "darby": "And when they shall say unto you, Seek unto the necromancers and unto the soothsayers, who chirp and who mutter, [say,] Shall not a people seek unto theirGod? [Will they go] for the living unto the dead?", "twenty": "", "jps": "And when they shall say unto you: 'Seek unto the ghosts and the familiar spirits, that chirp and that mutter; should not a people seek unto their G-d? on behalf of the living unto the dead", "acv": "And when they shall say to you, Seek for those who have familiar spirits and for the wizards, who chirp and who mutter, should not a people seek for their God? On behalf of the living seek to the dead?", "anderson": "", "haweis": "", "noyes": "And when they shall say to you, \"Inquire of the necromancers and the wizards, That chirp, and that murmur,\" [Then say ye,] \"Should not a people inquire of their God? Should they inquire of the dead for the living?\"", "webster": "And when they shall say to you, Seek to them that have familiar spirits, and to wizards that peep, and that mutter: should not a people seek to their God? for the living to the dead?", "vulgate": "et cum dixerint ad vos quaerite a pythonibus et a divinis qui stridunt in incantationibus suis numquid non populus a Deo suo requirit pro vivis a mortuis;", "brenton": "And if they should say to you, Seek those who have in them a divining spirit, and them that speak out of the earth, them that speak vain words, who speak out of their belly: shall not a nation diligently seek to their God? why do they seek to the dead concerning the living?"}}, {"v": 20, "ref": "8:20", "o": "לְ/תוֹרָ֖ה וְ/לִ/תְעוּדָ֑ה אִם לֹ֤א יֹֽאמְרוּ֙ כַּ/דָּבָ֣ר הַ/זֶּ֔ה אֲשֶׁ֥ר אֵֽין ל֖/וֹ שָֽׁחַר", "en": {"kjv": "To the law and to the testimony: if they speak not according to this word, it is because there is no light in them.", "web": "Turn to the law and to the testimony! If they don’t speak according to this word, surely there is no morning for them.", "bsb": "To the law and to the testimony! If they do not speak according to this word, they have no light of dawn.", "asv": "To the law and to the testimony! if they speak not according to this word, surely there is no morning for them.", "ylt": "To the law and to the testimony! If not, let them say after this manner, `That there is no dawn to it.'", "dra": "To the law rather, and to the testimony. And if they speak not according to this word, they shall not have the morning light.", "bbe": "Then say to them, Put your faith in the teaching and the witness. ... If they do not say such things. ... For him there is no dawn. ...", "geneva": "To the Law, and to the testimonie, if they speake not according to this worde: it is because there is no light in them.", "wycliffe": "It is to go to the lawe more and to the witnessyng, that if thei seien not after this word, morewtide liyt schal not be to hem.", "rotherham": "To the law and to the testimony! If they speak not according to this word, [It is], because they have no dawning day.", "darby": "To the law and the testimony! If they speak not according to this word, for them there is no daybreak.", "twenty": "", "jps": "for instruction and for testimony?' --Surely they will speak according to this word, wherein there is no light.--", "acv": "Seek to the law and to the testimony! If they speak not according to this word, surely there is no morning for them.", "anderson": "", "haweis": "", "noyes": "To the word, to the revelation! If they speak not according to this, For them no bright morning shall arise.", "webster": "To the law and to the testimony: if they speak not according to this word, [it is] because [there is] no light in them.", "vulgate": "ad legem magis et ad testimonium quod si non dixerint iuxta verbum hoc non erit eis matutina lux;", "brenton": "For he has given the law for a help, that they should not speak according to this word, concerning which there are no gifts to give for it."}}, {"v": 21, "ref": "8:21", "o": "וְ/עָ֥בַר בָּ֖/הּ נִקְשֶׁ֣ה וְ/רָעֵ֑ב וְ/הָיָ֨ה כִֽי יִרְעַ֜ב וְ/הִתְקַצַּ֗ף וְ/קִלֵּ֧ל בְּ/מַלְכּ֛/וֹ וּ/בֵ/אלֹהָ֖י/ו וּ/פָנָ֥ה לְ/מָֽעְלָ/ה", "en": {"kjv": "And they shall pass through it, hardly bestead and hungry: and it shall come to pass, that when they shall be hungry, they shall fret themselves, and curse their king and their God, and look upward.", "web": "They will pass through it, very distressed and hungry; and it will happen that when they are hungry, they will worry, and curse by their king and by their God. They will turn their faces upward,", "bsb": "They will roam the land, dejected and hungry. When they are famished, they will become enraged; and looking upward, they will curse their king and their God.", "asv": "And they shall pass through it, sore distressed and hungry; and it shall come to pass that, when they shall be hungry, they shall fret themselves, and curse by their king and by their God, and turn their faces upward:", "ylt": "--And it hath passed over into it, hardened and hungry, And it hath come to pass, That it is hungry, and hath been wroth, And made light of its king, and of its God, And hath looked upwards.", "dra": "And they shall pass by it, they shall fall, and be hungry: and when they shall be hungry, they will be angry, and curse their king, and their God, and look upwards.", "bbe": "And he will go through the land in bitter trouble and in need of food; and when he is unable to get food, he will become angry, cursing his king and his God, and his eyes will be turned to heaven on high;", "geneva": "Then he that is afflicted and famished, shall go to and from in it: and when he shalbe hungry, he shall euen freat himselfe, and curse his King and his gods, and shall looke vpward.", "wycliffe": "And it schal passe bi that, and it schal falle doun, and it schal hungre. And whanne it schal hungre, it schal be wrooth, and schal curse his kyng and his God, and it schal biholde vpward.", "rotherham": "Therefore shall they pass through it hard pressed and hungry,—And it shall be when they hunger, then will they rage and revile their king and their god and turn their faces upwards;", "darby": "And they shall pass through it, hard pressed and hungry; and it shall come to pass when they are hungry, they will fret themselves, and curse their king and theirGod, and will gaze upward:", "twenty": "", "jps": "And they shall pass this way that are sore bestead and hungry; and it shall come to pass that, when they shall be hungry, they shall fret themselves, and curse by their king and by their G-d, and, whether they turn their faces upward,", "acv": "And they shall pass through it, greatly distressed and hungry. And it shall come to pass that, when they shall be hungry, they shall fret themselves, and curse by their king and by their God, and turn their faces upward.", "anderson": "", "haweis": "", "noyes": "They shall pass through the land distressed and famished; And when they are famished, they shall be enraged, and curse their king and their God, And look upward.", "webster": "And they shall pass through it, distressed and hungry: and it shall come to pass, that when they shall be hungry, they shall fret themselves, and curse their king and their God, and look upward.", "vulgate": "et transibit per eam corruet et esuriet et cum esurierit irascetur et maledicet regi suo et Deo suo et suspiciet sursum;", "brenton": "And famine shall come sorely upon you, and it shall come to pass, that when ye shall be hungry, ye shall be grieved, and ye shall speak ill of the prince and your fathers' ordinances: and they shall look up to heaven above,"}}, {"v": 22, "ref": "8:22", "o": "וְ/אֶל אֶ֖רֶץ יַבִּ֑יט וְ/הִנֵּ֨ה צָרָ֤ה וַ/חֲשֵׁכָה֙ מְע֣וּף צוּקָ֔ה וַ/אֲפֵלָ֖ה מְנֻדָּֽח", "en": {"kjv": "And they shall look unto the earth; and behold trouble and darkness, dimness of anguish; and they shall be driven to darkness.", "web": "and look to the earth, and see distress, darkness, and the gloom of anguish. They will be driven into thick darkness.", "bsb": "Then they will look to the earth and see only distress and darkness and the gloom of anguish. And they will be driven into utter darkness.", "asv": "and they shall look unto the earth, and, behold, distress and darkness, the gloom of anguish; and into thick darkness they shall be driven away.", "ylt": "And unto the land it looketh attentively, And lo, adversity and darkness! --Dimness, distress, and thick darkness is driven away, But not the dimness for which she is in distress!", "dra": "And they shall look to the earth, and behold trouble and darkness, weakness and distress, and a mist following them, and they cannot fly away from their distress.", "bbe": "And he will be looking down on the earth, and there will be trouble and dark clouds, black night where there is no seeing.", "geneva": "And when he shall looke to the earth, beholde trouble, and darkenes, vexation and anguish, and he is driuen to darkenes.", "wycliffe": "And it schal loke to the erthe, and lo! tribulacioun, and derknessis, and vnbyndyng, ether discoumfort, and angwisch, and myist pursuynge; and it schal not mow fle awei fro his angwisch.", "rotherham": "And unto the land, shall they look hard, And lo! distress and darkness, the gloom of anguish, driven away!", "darby": "and they will look to the earth; and behold, trouble and darkness, gloom of anguish; and they shall be driven into thick darkness.", "twenty": "", "jps": "or look unto the earth, behold distress and darkness, the gloom of anguish, and outspread thick darkness.", "acv": "And they shall look to the earth, and, behold, distress and darkness, the gloom of anguish, and into thick darkness to be driven away.", "anderson": "", "haweis": "", "noyes": "And if they look to the earth, Behold distress and darkness, fearful darkness! And into darkness shall they be driven.", "webster": "And they shall look to the earth; and behold trouble and darkness, dimness of anguish; and [they shall be] driven to darkness.", "vulgate": "et ad terram intuebitur et ecce tribulatio et tenebrae dissolutio angustia et caligo persequens et non poterit avolare de angustia sua;", "brenton": "and they shall look on the earth below, and behold severe distress, and darkness, affliction, and anguish, and darkness so that one cannot see; and he that is in anguish shall not be distressed only for a time."}}]}, {"c": 9, "verses": [{"v": 1, "ref": "9:1", "o": "הָ/עָם֙ הַ/הֹלְכִ֣ים בַּ/חֹ֔שֶׁךְ רָא֖וּ א֣וֹר גָּד֑וֹל יֹשְׁבֵי֙ בְּ/אֶ֣רֶץ צַלְמָ֔וֶת א֖וֹר נָגַ֥הּ עֲלֵי/הֶֽם", "en": {"kjv": "Nevertheless the dimness shall not be such as was in her vexation, when at the first he lightly afflicted the land of Zebulun and the land of Naphtali, and afterward did more grievously afflict her by the way of the sea, beyond Jordan, in Galilee of the nations.", "web": "But there shall be no more gloom for her who was in anguish. In the former time, he brought into contempt the land of Zebulun and the land of Naphtali; but in the latter time he has made it glorious, by the way of the sea, beyond the Jordan, Galilee of the nations.", "bsb": "Nevertheless, there will be no more gloom for those in distress. In the past He humbled the land of Zebulun and the land of Naphtali, but in the future He will honor the Way of the Sea, beyond the Jordan, Galilee of the nations:", "asv": "But there shall be no gloom to her that was in anguish. In the former time he brought into contempt the land of Zebulun and the land of Naphtali; but in the latter time hath he made it glorious, by the way of the sea, beyond the Jordan, Galilee of the nations.", "ylt": "As the former time made light The land of Zebulun and the land of Naphtali, So the latter hath honoured the way of the sea, Beyond the Jordan, Galilee of the nations.", "dra": "At the first time the land of Zabulon, and the land of Nephtali was lightly touched: and at the last the way of the sea beyond the Jordan of the Galilee of the Gentiles was heavily loaded.", "bbe": "In earlier times he made the land of Zebulun and the land of Naphtali of small value, but after that he gave it glory, by the way of the sea, on the other side of Jordan, Galilee of the nations.", "geneva": "Yet the darkenesse shall not be according to the affliction that it had when at the first hee touched lightly the land of Zebulun and the land of Naphtali, nor afteward when he was more grieuous by the way of the sea beyond Iorden in Galile of the Gentiles.", "wycliffe": "In the firste tyme the lond of Zabulon and the lond of Neptalym was releessid; and at the laste the weie of the see biyende Jordan of Galile of hethene men was maad heuy.", "rotherham": "For there is no gloom to her who had been in anguish, In the former time, he brought into dishonour The land of Zebulun and the land of Naphtali, In the latter time, hath he brought into honour The Lake-way over the Jordan, Galilee of the nations.", "darby": "Nevertheless the darkness shall not be as when the distress was in the [land], at the time he at first lightly, and afterwards heavily, visited the land of Zebulun and the land of Naphtali, — the way of the sea, beyond the Jordan, Galilee of the nations:", "twenty": "", "jps": "The people that walked in darkness have seen a great light; they that dwelt in the land of the shadow of death, upon them hath the light shined.", "acv": "But there shall be no gloom to her who was in anguish. In the former time he brought into contempt the land of Zebulun and the land of Naphtali, but in the latter time he has made it glorious, by the way of the sea, beyond the Jordan, Galilee of the Gentiles.", "anderson": "", "haweis": "", "noyes": "But the darkness shall not remain where now is distress; Of old he brought the land of Zebulon and the land of Naphtali into contempt; In future times shall he bring the land of the sea beyond Jordan, the circle of the gentiles, into honor.", "webster": "Nevertheless the dimness [shall] not [be] such as [was] in her distress, when at the first he lightly afflicted the land of Zebulun, and the land of Naphtali, and afterward did more grievously afflict [her by] the way of the sea, beyond Jordan, in Galilee of the nations.", "vulgate": "primo tempore adleviata est terra Zabulon et terra Nepthalim et novissimo adgravata est via maris trans Iordanem Galileae gentium;", "brenton": "Drink this first. Act quickly, O land of Zabulon, land of Nephthalim, and the rest inhabiting the sea-coast, and the land beyond Jordan, Galilee of the Gentiles."}}, {"v": 2, "ref": "9:2", "o": "הִרְבִּ֣יתָ הַ/גּ֔וֹי לא ל֖/וֹ הִגְדַּ֣לְתָּ הַ/שִּׂמְחָ֑ה שָׂמְח֤וּ לְ/פָנֶ֨י/ךָ֙ כְּ/שִׂמְחַ֣ת בַּ/קָּצִ֔יר כַּ/אֲשֶׁ֥ר יָגִ֖ילוּ בְּ/חַלְּקָ֥/ם שָׁלָֽל", "en": {"kjv": "The people that walked in darkness have seen a great light: they that dwell in the land of the shadow of death, upon them hath the light shined.", "web": "The people who walked in darkness have seen a great light. Those who lived in the land of the shadow of death, on them the light has shined.", "bsb": "The people walking in darkness have seen a great light; on those living in the land of the shadow of death, a light has dawned.", "asv": "The people that walked in darkness have seen a great light: they that dwelt in the land of the shadow of death, upon them hath the light shined.", "ylt": "The people who are walking in darkness Have seen a great light, Dwellers in a land of death-shade, Light hath shone upon them.", "dra": "The people that walked in darkness, have seen a great light: to them that dwelt in the region of the shadow of death, light is risen.", "bbe": "The people who went in the dark have seen a great light, and for those who were living in the land of the deepest night, the light is shining.", "geneva": "The people that walked in darkenes haue seene a great light: they that dwelled in the land of the shadowe of death, vpon them hath the light shined.", "wycliffe": "The puple that yede in derknessis siy a greet liyt; whanne men dwelliden in the cuntre of schadewe of deth, liyt roos vp to hem.", "rotherham": "the people who were walking in darkness, Have seen a great light,—The dwellers in a land death-shadowed, A light, hath shined upon them.", "darby": "the people that walked in darkness have seen a great light; they that dwelt in the land of the shadow of death, upon them light hath shone.", "twenty": "", "jps": "Thou hast multiplied the nation, Thou hast increased their joy; they joy before Thee according to the joy in harvest, as men rejoice when they divide the spoil.", "acv": "The people who walked in darkness have seen a great light. Those who dwelt in the land of the shadow of death, upon them the light has shone.", "anderson": "", "haweis": "", "noyes": "The people that walk in darkness behold a great light; They who dwell in the land of death-like shade, Upon them a light shineth.", "webster": "The people that walked in darkness have seen a great light: they that dwell in the land of the shades of death, upon them hath the light shined.", "vulgate": "populus qui ambulabat in tenebris vidit lucem magnam habitantibus in regione umbrae mortis lux orta est eis;", "brenton": "O people walking in darkness, behold a great light: ye that dwell in the region and shadow of death, a light shall shine upon you."}}, {"v": 3, "ref": "9:3", "o": "כִּ֣י אֶת עֹ֣ל סֻבֳּל֗/וֹ וְ/אֵת֙ מַטֵּ֣ה שִׁכְמ֔/וֹ שֵׁ֖בֶט הַ/נֹּגֵ֣שׂ בּ֑/וֹ הַחִתֹּ֖תָ כְּ/י֥וֹם מִדְיָֽן", "en": {"kjv": "Thou hast multiplied the nation, and not increased the joy: they joy before thee according to the joy in harvest, and as men rejoice when they divide the spoil.", "web": "You have multiplied the nation. You have increased their joy. They rejoice before you according to the joy in harvest, as men rejoice when they divide the plunder.", "bsb": "You have enlarged the nation and increased its joy. The people rejoice before You as they rejoice at harvest time, as men rejoice in dividing the plunder.", "asv": "Thou hast multiplied the nation, thou hast increased their joy: they joy before thee according to the joy in harvest, as men rejoice when they divide the spoil.", "ylt": "Thou hast multiplied the nation, Thou hast made great its joy, They have joyed before Thee as the joy in harvest, As men rejoice in their apportioning spoil.", "dra": "Thou hast multiplied the nation, and hast not increased the joy. They shall rejoice before thee, as they that rejoice in the harvest, as conquerors rejoice after taking a prey, when they divide the spoils.", "bbe": "You have made them very glad, increasing their joy. They are glad before you as men are glad in the time of getting in the grain, or when they make division of the goods taken in war.", "geneva": "Thou hast multiplied the nation, and not increased their ioye: they haue reioyced before thee according to the ioye in haruest, and as men reioyce when they deuide a spoyle.", "wycliffe": "Thou multipliedist folk, thou magnefiedist not gladnesse; thei schulen be glad bifore thee, as thei that ben glad in heruest, as ouercomeris maken ful out ioie, whanne thei han take a prey, whanne thei departen the spuylis.", "rotherham": "Thou hast increased the exultation Thou hast made great the joy,—They joy before thee, according to the joy of harvest, As men exult when they distribute spoil.", "darby": "Thou hast multiplied the nation, hast increased its joy: they joy before thee like to the joy in harvest; as [men] rejoice when they divide the spoil.", "twenty": "", "jps": "For the yoke of his burden, and the staff of his shoulder, the rod of his oppressor, Thou hast broken as in the day of Midian.", "acv": "Thou have multiplied the nation. Thou have increased their joy. They joy before thee according to the joy in harvest, as men rejoice when they divide the spoil.", "anderson": "", "haweis": "", "noyes": "Thou enlargest the nation; Thou increasest their joy; They rejoice before thee with the joy of harvest, With the joy of those who divide the spoil.", "webster": "Thou hast multiplied the nation, [and] not increased the joy: they joy before thee according to the joy in harvest, [and] as [men] rejoice when they divide the spoil.", "vulgate": "multiplicasti gentem non magnificasti laetitiam laetabuntur coram te sicut laetantur in messe sicut exultant quando dividunt spolia;", "brenton": "The multitude of the people which thou hast brought down in thy joy, they shall even rejoice before thee as they that rejoice in harvest, and as they that divide the spoil."}}, {"v": 4, "ref": "9:4", "o": "כִּ֤י כָל סְאוֹן֙ סֹאֵ֣ן בְּ/רַ֔עַשׁ וְ/שִׂמְלָ֖ה מְגוֹלָלָ֣ה בְ/דָמִ֑ים וְ/הָיְתָ֥ה לִ/שְׂרֵפָ֖ה מַאֲכֹ֥לֶת אֵֽשׁ", "en": {"kjv": "For thou hast broken the yoke of his burden, and the staff of his shoulder, the rod of his oppressor, as in the day of Midian.", "web": "For the yoke of his burden, and the staff of his shoulder, the rod of his oppressor, you have broken as in the day of Midian.", "bsb": "For as in the day of Midian You have shattered the yoke of their burden, the bar across their shoulders, and the rod of their oppressor.", "asv": "For the yoke of his burden, and the staff of his shoulder, the rod of his oppressor, thou hast broken as in the day of Midian.", "ylt": "Because the yoke of its burden, And the staff of its shoulder, the rod of its exactor, Thou hast broken as in the day of Midian.", "dra": "For the yoke of their burden, and the rod of their shoulder, and the sceptre of their oppressor thou hast overcome, as in the day of Madian.", "bbe": "For by your hand the yoke on his neck and the rod on his back, even the rod of his cruel master, have been broken, as in the day of Midian.", "geneva": "For the yoke of their burthen, and the staffe of their shoulder and the rod of their oppressour hast thou broken as in the day of Midian.", "wycliffe": "For thou hast ouercome the yok of his birthun, and the yerde of his schuldre, and the ceptre of his wrongful axere, as in the day of Madian.", "rotherham": "For, the yoke of their burden, The cross-bar of their shoulder, The goad of their driver, Hast thou broken, as in the day of Midian.", "darby": "For thou hast broken the yoke of his burden and the staff of his shoulder, the rod of his oppressor, as in the day of Midian.", "twenty": "", "jps": "For every boot stamped with fierceness, and every cloak rolled in blood, shall even be for burning, for fuel of fire.", "acv": "For the yoke of his burden, and the staff of his shoulder, the rod of his oppressor, thou have broken as in the day of Midian.", "anderson": "", "haweis": "", "noyes": "For thou breakest their heavy yoke, And the rod that smote their backs, And the scourge of the taskmaster, As in the day of Midian.", "webster": "For thou hast broken the yoke of his burden, and the staff of his shoulder, the rod of his oppressor, as in the day of Midian.", "vulgate": "iugum enim oneris eius et virgam umeri eius et sceptrum exactoris eius superasti sicut in die Madian;", "brenton": "Because the yoke that was laid upon them has been taken away, and the rod that was on their neck: for he has broken the rod of the exactors, as in the day of Madiam."}}, {"v": 5, "ref": "9:5", "o": "כִּי יֶ֣לֶד יֻלַּד לָ֗/נוּ בֵּ֚ן נִתַּן לָ֔/נוּ וַ/תְּהִ֥י הַ/מִּשְׂרָ֖ה עַל שִׁכְמ֑/וֹ וַ/יִּקְרָ֨א שְׁמ֜/וֹ פֶּ֠לֶא יוֹעֵץ֙ אֵ֣ל גִּבּ֔וֹר אֲבִי עַ֖ד שַׂר שָׁלֽוֹם", "en": {"kjv": "For every battle of the warrior is with confused noise, and garments rolled in blood; but this shall be with burning and fuel of fire.", "web": "For all the armor of the armed man in the noisy battle, and the garments rolled in blood, will be for burning, fuel for the fire.", "bsb": "For every trampling boot of battle and every garment rolled in blood will be burned as fuel for the fire.", "asv": "For all the armor of the armed man in the tumult, and the garments rolled in blood, shall be for burning, for fuel of fire.", "ylt": "For every battle of a warrior is with rushing, and raiment rolled in blood, And it hath been for burning--fuel of fire.", "dra": "For every violent taking of spoils, with tumult, and garment mingled with blood, shall be burnt, and be fuel for the fire.", "bbe": "For every boot of the man of war with his sounding step, and the clothing rolled in blood, will be for burning, food for the fire.", "geneva": "Surely euery battell of the warriour is with noyse, and with tumbling of garments in blood: but this shall be with burning and deuouring of fire.", "wycliffe": "For whi al violent raueyn with noise, and a cloth meddlid with blood schal be in to brennyng, and `schal be the mete of fier.", "rotherham": "Surely, every boot of one tramping in tumult, and the war-cloak rolled in blood Then shall serve for burning, food for fire;", "darby": "For every boot of him that is shod for the tumult, and the garment rolled in blood, shall be for burning, fuel for fire.", "twenty": "", "jps": "For a child is born unto us, a son is given unto us; and the government is upon his shoulder; and his name is called Pele-joez-el-gibbor-Abi-ad-sar-shalom;", "acv": "For all the armor of the armed man in the tumult, and the garments rolled in blood, shall be for burning, for fuel of fire.", "anderson": "", "haweis": "", "noyes": "For every greave of the warrior in battle, And the war-garment rolled in blood, Shall be burned; yea, it shall be food for the fire.", "webster": "For every battle of the warrior [is] with confused noise, and garments rolled in blood; but [this] shall be with burning [and] fuel of fire.", "vulgate": "quia omnis violenta praedatio cum tumultu et vestimentum mixtum sanguine erit in conbustionem et cibus ignis;", "brenton": "For they shall compensate for every garment that has been acquired by deceit, and all raiment with restitution; and they shall be willing, even if they were burnt with fire."}}, {"v": 6, "ref": "9:6", "o": "ל/םרבה לְ/מַרְבֵּ֨ה הַ/מִּשְׂרָ֜ה וּ/לְ/שָׁל֣וֹם אֵֽין קֵ֗ץ עַל כִּסֵּ֤א דָוִד֙ וְ/עַל מַמְלַכְתּ֔/וֹ לְ/הָכִ֤ין אֹתָ/הּ֙ וּֽ/לְ/סַעֲדָ֔/הּ בְּ/מִשְׁפָּ֖ט וּ/בִ/צְדָקָ֑ה מֵ/עַתָּה֙ וְ/עַד עוֹלָ֔ם קִנְאַ֛ת יְהוָ֥ה צְבָא֖וֹת תַּעֲשֶׂה זֹּֽאת", "en": {"kjv": "For unto us a child is born, unto us a son is given: and the government shall be upon his shoulder: and his name shall be called Wonderful, Counsellor, The mighty God, The everlasting Father, The Prince of Peace.", "web": "For to us a child is born. To us a son is given; and the government will be on his shoulders. His name will be called Wonderful, Counselor, Mighty God, Everlasting Father, Prince of Peace.", "bsb": "For unto us a child is born, unto us a son is given, and the government will be upon His shoulders. And He will be called Wonderful Counselor, Mighty God, Everlasting Father, Prince of Peace.", "asv": "For unto us a child is born, unto us a son is given; and the government shall be upon his shoulder: and his name shall be called Wonderful, Counsellor, Mighty God, Everlasting Father, Prince of Peace.", "ylt": "For a Child hath been born to us, A Son hath been given to us, And the princely power is on his shoulder, And He doth call his name Wonderful, Counsellor, Mighty God, Father of Eternity, Prince of Peace.", "dra": "For a CHILD IS BORN to us, and a son is given to us, and the government is upon his shoulder: and his name shall be called Wonderful, Counsellor, God the Mighty, the Father of the world to come, the Prince of Peace.", "bbe": "For to us a child has come, to us a son is given; and the government has been placed in his hands; and he has been named Wise Guide, Strong God, Father for ever, Prince of Peace.", "geneva": "For vnto vs a childe is borne, and vnto vs a Sonne is giuen: and the gouernement is vpon his shoulder, and he shall call his name Wonderfull, Counseller, The mightie God, The euerlasting Father, The prince of peace,", "wycliffe": "Forsothe a litil child is borun to vs, and a sone is youun to vs, and prinsehod is maad on his schuldre; and his name schal be clepid Wondurful, A counselour, God, Strong, A fadir of the world to comynge, A prince of pees.", "rotherham": "For, A Child, hath been born to us, A Son, hath been given to us, And the dominion is upon his shoulder,—And his Name hath been called Wonderful Counsellor, Mighty GOD, Father of Futurity, Prince of Prosperity.", "darby": "For unto us a child is born, unto us a son is given; and the government shall be upon his shoulder; and his name is called Wonderful, Counsellor, MightyGod, Father of Eternity, Prince of Peace.", "twenty": "", "jps": "That the government may be increased, and of peace there be no end, upon the throne of David, and upon his kingdom, to establish it, and to uphold it through justice and through righteousness from henceforth even for ever. The zeal of HaShem of hosts doth perform this.", "acv": "For to us a child is born, to us a son is given. And the government shall be upon his shoulder. And his name shall be called Wonderful, Counselor, Mighty God, Father of Eternity, Prince of Peace.", "anderson": "", "haweis": "", "noyes": "For to us a child is born, To us a son is given, And the government shall be upon his shoulder, And he shall be called Wonderful, counsellor, mighty potentate, Everlasting father, prince of peace;", "webster": "For to us a child is born, to us a son is given: and the government shall be upon his shoulder: and his name shall be called Wonderful, Counselor, The mighty God, The everlasting Father, The Prince of Peace.", "vulgate": "parvulus enim natus est nobis filius datus est nobis et factus est principatus super umerum eius et vocabitur nomen eius Admirabilis consiliarius Deus fortis Pater futuri saeculi Princeps pacis;", "brenton": "For a child is born to us, and a son is given to us, whose government is upon his shoulder: and his name is called the Messenger of great counsel: for I will bring peace upon the princes, and health to him."}}, {"v": 7, "ref": "9:7", "o": "דָּבָ֛ר שָׁלַ֥ח אֲדֹנָ֖/י בְּ/יַעֲקֹ֑ב וְ/נָפַ֖ל בְּ/יִשְׂרָאֵֽל", "en": {"kjv": "Of the increase of his government and peace there shall be no end, upon the throne of David, and upon his kingdom, to order it, and to establish it with judgment and with justice from henceforth even for ever. The zeal of the Lord of hosts will perform this.", "web": "Of the increase of his government and of peace there shall be no end, on the throne of David, and on his kingdom, to establish it, and to uphold it with justice and with righteousness from that time on, even forever. The zeal of Yahweh of Armies will perform this.", "bsb": "Of the increase of His government and peace there will be no end. He will reign on the throne of David and over his kingdom, to establish and sustain it with justice and righteousness from that time and forevermore. The zeal of the LORD of Hosts will accomplish this.", "asv": "Of the increase of his government and of peace there shall be no end, upon the throne of David, and upon his kingdom, to establish it, and to uphold it with justice and with righteousness from henceforth even for ever. The zeal of Jehovah of hosts will perform this.", "ylt": "To the increase of the princely power, And of peace, there is no end, On the throne of David, and on his kingdom, To establish it, and to support it, In judgment and in righteousness, Henceforth, even unto the age, The zeal of Jehovah of Hosts doth this.", "dra": "His empire shall be multiplied, and there shall be no end of peace: he shall sit upon the throne of David, and upon his kingdom; to establish it and strengthen it with judgment and with justice, from henceforth and for ever: the zeal of the Lord of hosts will perform this.", "bbe": "Of the increase of his rule and of peace there will be no end, on the seat of David, and in his kingdom; to make it strong, supporting it with wise decision and righteousness, now and for ever. By the fixed purpose of the Lord of armies this will be done.", "geneva": "The increase of his gouernement and peace shall haue none end: he shall sit vpon the throne of Dauid, and vpon his kingdome, to order it, and to stablish it with iudgement and with iustice, from hencefoorth, euen for euer: the zeale of the Lord of hostes will performe this.", "wycliffe": "His empire schal be multiplied, and noon ende schal be of his pees; he schal sitte on the seete of Dauid, and on the rewme of hym, that he conferme it, and make stronge in doom and riytfulnesse, fro hennus forth and til in to with outen ende. The feruent loue of the Lord of oostis schal make this.", "rotherham": "Of the increase of dominion, and of prosperity, There shall be no end—Upon the throne of David and Upon his kingdom, By establishing it and By sustaining it, With justice and With righteousness,—From henceforth, Even unto times age-abiding: The jealousy of Yahweh of hosts, will perform this!", "darby": "Of the increase of his government and of peace there shall be no end, upon the throne of David and over his kingdom, to establish it, and to uphold it with judgment and with righteousness, from henceforth even for ever. The zeal of Jehovah of hosts will perform this.", "twenty": "", "jps": "The L-rd sent a word into Jacob, and it hath lighted upon Israel.", "acv": "Of the increase of his government and of peace there shall be no end, upon the throne of David, and upon his kingdom, to establish it, and to uphold it with justice and with righteousness from henceforth even forever. The zeal of Jehovah of hosts will perform this.", "anderson": "", "haweis": "", "noyes": "His dominion shall be great, And peace without end shall be upon the throne of David and his kingdom, To fix and establish it Through justice and equity, Henceforth and forever. The zeal of Jehovah of hosts will do this.", "webster": "Of the increase of [his] government and peace [there shall be] no end, upon the throne of David, and upon his kingdom, to order it, and to establish it with judgment and with justice from henceforth even for ever. The zeal of the LORD of hosts will perform this.", "vulgate": "multiplicabitur eius imperium et pacis non erit finis super solium David et super regnum eius ut confirmet illud et corroboret in iudicio et iustitia amodo et usque in sempiternum zelus Domini exercituum faciet hoc;", "brenton": "His government shall be great, and of his peace there is no end: it shall be upon the throne of David, and upon his kingdom, to establish it, and to support it with judgment and with righteousness, from henceforth and forever. The seal of the Lord of hosts shall perform this."}}, {"v": 8, "ref": "9:8", "o": "וְ/יָדְעוּ֙ הָ/עָ֣ם כֻּלּ֔/וֹ אֶפְרַ֖יִם וְ/יוֹשֵׁ֣ב שֹׁמְר֑וֹן בְּ/גַאֲוָ֛ה וּ/בְ/גֹ֥דֶל לֵבָ֖ב לֵ/אמֹֽר", "en": {"kjv": "The Lord sent a word into Jacob, and it hath lighted upon Israel.", "web": "The Lord sent a word into Jacob, and it falls on Israel.", "bsb": "The Lord has sent a message against Jacob, and it has fallen upon Israel.", "asv": "The Lord sent a word into Jacob, and it hath lighted upon Israel.", "ylt": "A word hath the Lord sent into Jacob, And it hath fallen in Israel.", "dra": "The Lord sent a word into Jacob, and it hath lighted upon Israel.", "bbe": "The Lord has sent a word to Jacob, and it has come on Israel;", "geneva": "The Lord hath sent a worde into Iaakob, and it hath lighted vpon Israel.", "wycliffe": "The Lord sente a word in to Jacob, and it felle in Israel.", "rotherham": "A word, hath My Lord, sent unto Jacob,—And it shall alight on Israel;", "darby": "The Lord sent a word unto Jacob, and it lighteth upon Israel.", "twenty": "", "jps": "And all the people shall know, even Ephraim and the inhabitant of Samaria, that say in pride and in arrogancy of heart:", "acv": "The Lord sent a word into Jacob, and it has lighted upon Israel.", "anderson": "", "haweis": "", "noyes": "The Lord sendeth a word against Jacob; It cometh down to Israel.", "webster": "The Lord sent a word into Jacob, and it hath lighted upon Israel.", "vulgate": "verbum misit Dominus in Iacob et cecidit in Israhel;", "brenton": "The Lord has sent death upon Jacob, and it has come upon Israel."}}, {"v": 9, "ref": "9:9", "o": "לְבֵנִ֥ים נָפָ֖לוּ וְ/גָזִ֣ית נִבְנֶ֑ה שִׁקְמִ֣ים גֻּדָּ֔עוּ וַ/אֲרָזִ֖ים נַחֲלִֽיף", "en": {"kjv": "And all the people shall know, even Ephraim and the inhabitant of Samaria, that say in the pride and stoutness of heart,", "web": "All the people will know, including Ephraim and the inhabitants of Samaria, who say in pride and in arrogance of heart,", "bsb": "All the people will know it— Ephraim and the dwellers of Samaria. With pride and arrogance of heart they will say:", "asv": "And all the people shall know, even Ephraim and the inhabitant of Samaria, that say in pride and in stoutness of heart,", "ylt": "And the people have known--all of it, Ephraim, and the inhabitant of Samaria, In pride and in greatness of heart, saying,", "dra": "And all the people of Ephraim shall know, and the inhabitants of Samaria that say in the pride and haughtiness of their heart:", "bbe": "And all the people will have experience of it, even Ephraim and the men of Samaria, who say in the pride of their uplifted hearts,", "geneva": "And all the people shall knowe, euen Ephraim, and the inhabitant of Samaria, that say in the pride and presumption of the heart,", "wycliffe": "And al the puple of Effraym schal wite, and thei that dwellen in Samarie, seiynge in the pride and greetnesse of herte,", "rotherham": "and the people shall all of them know [it] —Ephraim and the dweller in Samaria—Who in pride and insolence of heart, are saying:", "darby": "And all the people shall know [it], Ephraim and the inhabitant of Samaria, that say in pride and stoutness of heart,", "twenty": "", "jps": "'The bricks are fallen, but we will build with hewn stones; the sycamores are cut down, but cedars will we put in their place.'", "acv": "And all the people shall know, even Ephraim and the inhabitant of Samaria, who say in pride and in arrogance of heart,", "anderson": "", "haweis": "", "noyes": "His whole people shall feel it, Ephraim, and the inhabitants of Samaria, Who say in pride and arrogance of heart,", "webster": "And all the people shall know, [even] Ephraim and the inhabitant of Samaria, that say in the pride and stoutness of heart,", "vulgate": "et sciet populus omnis Ephraim et habitantes Samariam in superbia et magnitudine cordis dicentes;", "brenton": "And all the people of Ephraim, and they that dwelt in Samaria shall know, who say in their pride and lofty heart,"}}, {"v": 10, "ref": "9:10", "o": "וַ/יְשַׂגֵּ֧ב יְהוָ֛ה אֶת צָרֵ֥י רְצִ֖ין עָלָ֑י/ו וְ/אֶת אֹיְבָ֖י/ו יְסַכְסֵֽךְ", "en": {"kjv": "The bricks are fallen down, but we will build with hewn stones: the sycomores are cut down, but we will change them into cedars.", "web": "“The bricks have fallen, but we will build with cut stone. The sycamore fig trees have been cut down, but we will put cedars in their place.”", "bsb": "“The bricks have fallen, but we will rebuild with finished stone; the sycamores have been felled, but we will replace them with cedars.”", "asv": "The bricks are fallen, but we will build with hewn stone; the sycomores are cut down, but we will put cedars in their place.", "ylt": "`Bricks have fallen, and hewn work we build, Sycamores have been cut down, and cedars we renew.'", "dra": "The bricks are fallen down, but we will build with square stones: they have cut down the sycamores, but we will change them for cedars.", "bbe": "The bricks have come down, but we will put up buildings of cut stone in their place: the sycamores are cut down, but they will be changed to cedars.", "geneva": "The brickes are fallen, but we will build it with hewen stones: the wilde figge trees are cut downe, but we will change them into ceders.", "wycliffe": "Tijl stoonys fellen doun, but we schulen bilde with square stoonys; thei han kit doun sicomoris, but we schulen chaunge cedris.", "rotherham": "Bricks, have fallen down But with hewn stone, will we build,—Sycomores, have been felled, But with cedars, will we replace them.", "darby": "The bricks are fallen down, but we will build with hewn stones; the sycamore trees are cut down, but we will replace them with cedars.", "twenty": "", "jps": "Therefore HaShem doth set upon high the adversaries of Rezin against him, and spur his enemies;", "acv": "The bricks are fallen, but we will build with hewn stone, the sycamores are cut down, but we will put cedars in their place.", "anderson": "", "haweis": "", "noyes": "\"The bricks are fallen down, but we will build with hewn stones; The sycamores are cut down, but we will replace them with cedars.\"", "webster": "The bricks have fallen down, but we will build with hewn stones; the sycamores are cut down, but we will change [them into] cedars.", "vulgate": "lateres ceciderunt sed quadris lapidibus aedificabimus sycomoros succiderunt sed cedros inmutabimus;", "brenton": "The bricks are fallen down, but come, let us hew stones, and cut down sycamores and cedars, and let us build for ourselves a tower."}}, {"v": 11, "ref": "9:11", "o": "אֲרָ֣ם מִ/קֶּ֗דֶם וּ/פְלִשְׁתִּים֙ מֵֽ/אָח֔וֹר וַ/יֹּאכְל֥וּ אֶת יִשְׂרָאֵ֖ל בְּ/כָל פֶּ֑ה בְּ/כָל זֹאת֙ לֹא שָׁ֣ב אַפּ֔/וֹ וְ/ע֖וֹד יָד֥/וֹ נְטוּיָֽה", "en": {"kjv": "Therefore the Lord shall set up the adversaries of Rezin against him, and join his enemies together;", "web": "Therefore Yahweh will set up on high against him the adversaries of Rezin, and will stir up his enemies,", "bsb": "The LORD has raised up the foes of Rezin against him and joined his enemies together.", "asv": "Therefore Jehovah will set up on high against him the adversaries of Rezin, and will stir up his enemies,", "ylt": "And Jehovah setteth the adversaries of Rezin on high above him, And his enemies he joineth together,", "dra": "And the Lord shall set up the enemies of Rasin over him, and shall bring on his enemies in a crowd:", "bbe": "For this cause the Lord has made strong the haters of Israel, driving them on to make war against him;", "geneva": "Neuerthelesse the Lord will raise vp the aduersaries of Rezin against him, and ioyne his enemies together.", "wycliffe": "And the Lord schal reise the enemyes of Rasyn on hym, and he schal turne the enemyes of hym in to noyse;", "rotherham": "Therefore will Yahweh strengthen the adversaries of Resin against him,—And his enemies will he arouse:", "darby": "And Jehovah will set up the adversaries of Rezin against him, and arm his enemies,", "twenty": "", "jps": "The Arameans on the east, and the Philistines on the west; and they devour Israel with open mouth. For all this His anger is not turned away, but His hand is stretched out still.", "acv": "Therefore Jehovah will set up on high against him the adversaries of Rezin, and will stir up his enemies,", "anderson": "", "haweis": "", "noyes": "Jehovah will raise up the enemies of Rezin against them, And will arm their adversaries;", "webster": "Therefore the LORD will set up the adversaries of Rezin against him, and join his enemies together;", "vulgate": "et elevabit Dominus hostes Rasin super eum et inimicos eius in tumultum vertet;", "brenton": "And God shall dash down them that rise up against him on mount Sion, and shall scatter his enemies;"}}, {"v": 12, "ref": "9:12", "o": "וְ/הָ/עָ֥ם לֹא שָׁ֖ב עַד הַ/מַּכֵּ֑/הוּ וְ/אֶת יְהוָ֥ה צְבָא֖וֹת לֹ֥א דָרָֽשׁוּ", "en": {"kjv": "The Syrians before, and the Philistines behind; and they shall devour Israel with open mouth. For all this his anger is not turned away, but his hand is stretched out still.", "web": "The Syrians in front, and the Philistines behind; and they will devour Israel with open mouth. For all this, his anger is not turned away, but his hand is stretched out still.", "bsb": "Aram from the east and Philistia from the west have devoured Israel with open mouths. Despite all this, His anger is not turned away; His hand is still upraised.", "asv": "the Syrians before, and the Philistines behind; and they shall devour Israel with open mouth. For all this his anger is not turned away, but his hand is stretched out still.", "ylt": "Aram from before, and Philistia from behind, And they devour Israel with the whole mouth. With all this not turned back hath His anger, And still His hand is stretched out.", "dra": "The Syrians from the east, and, the Philistines from the west: and they shall devour Israel with open mouth. For all this his indignation is not turned away, but his hand is stretched out still.", "bbe": "Aram on the east, and the Philistines on the west, who have come against Israel with open mouths. For all this his wrath is not turned away, but his hand is stretched out still.", "geneva": "Aram before and the Philistims behinde, and they shall deuoure Israel with open mouth: yet for all this his wrath is not turned away, but his hand is stretched out still.", "wycliffe": "God schal make Sirie to come fro the eest, and Filisteis fro the west; and with al the mouth thei schulen deuoure Israel. In alle these thingis the stronge veniaunce of the Lord is not turned awei, but yit his hond is stretchid forth;", "rotherham": "Syrians before and Philistines behind, Thus have they devoured Israel with open mouth,—For all this, hath his anger, not turned back, But still, is his hand outstretched.", "darby": "the Syrians on the east, and the Philistines on the west; and they shall devour Israel with open mouth. For all this his anger is not turned away, and his hand is stretched out still.", "twenty": "", "jps": "Yet the people turneth not unto Him that smiteth them, neither do they seek HaShem of hosts.", "acv": "the Syrians in front, and the Philistines behind, and they shall devour Israel with open mouth. For all this his anger is not turned away, but his hand is stretched out still.", "anderson": "", "haweis": "", "noyes": "The Syrians before, the Philistines behind, Who shall devour Israel with wide jaws. For all this his anger is not turned away, But his hand is stretched out still.", "webster": "The Syrians before, and the Philistines behind; and they shall devour Israel with open mouth. For all this his anger is not turned away, but his hand [is] stretched out still.", "vulgate": "Syriam ab oriente et Philisthim ab occidente et devorabunt Israhel toto ore in omnibus his non est aversus furor eius sed adhuc manus eius extenta;", "brenton": "even Syria from the rising of the sun, and the Greeks from the setting of the sun, who devour Israel with open mouth. For all this his anger is not turned away, but still his hand is exalted."}}, {"v": 13, "ref": "9:13", "o": "וַ/יַּכְרֵ֨ת יְהוָ֜ה מִ/יִּשְׂרָאֵ֗ל רֹ֧אשׁ וְ/זָנָ֛ב כִּפָּ֥ה וְ/אַגְמ֖וֹן י֥וֹם אֶחָֽד", "en": {"kjv": "For the people turneth not unto him that smiteth them, neither do they seek the Lord of hosts.", "web": "Yet the people have not turned to him who struck them, neither have they sought Yahweh of Armies.", "bsb": "But the people did not return to Him who struck them; they did not seek the LORD of Hosts.", "asv": "Yet the people have not turned unto him that smote them, neither have they sought Jehovah of hosts.", "ylt": "And the people hath not turned back unto Him who is smiting it, And Jehovah of Hosts they have not sought.", "dra": "And the people are not returned to him who hath struck them, and have not sought after the Lord of hosts.", "bbe": "But the heart of the people was not turned to him who sent punishment on them, and they made no prayer to the Lord of armies.", "geneva": "For the people turneth not vnto him that smiteth them, neither doe they seeke the Lord of hostes.", "wycliffe": "and the puple is not turned ayen to the Lord smytynge it, and thei souyten not the Lord of oostis.", "rotherham": "Yet, the people, have not turned unto him that smote them,—And Yahweh of hosts, have they not sought.", "darby": "But the people turneth not unto him that smiteth them, and they do not seek Jehovah of hosts.", "twenty": "", "jps": "Therefore HaShem doth cut off from Israel head and tail, palm-branch and rush, in one day.", "acv": "Yet the people have not turned to him who smote them, nor have they sought Jehovah of hosts.", "anderson": "", "haweis": "", "noyes": "The people turn not to him that smiteth them; Neither do they seek Jehovah of hosts.", "webster": "For the people turn not to him that smiteth them, neither do they seek the LORD of hosts.", "vulgate": "et populus non est reversus ad percutientem se et Dominum exercituum non inquisierunt;", "brenton": "But the people turned not until they were smitten, and they sought not the Lord."}}, {"v": 14, "ref": "9:14", "o": "זָקֵ֥ן וּ/נְשׂוּא פָנִ֖ים ה֣וּא הָ/רֹ֑אשׁ וְ/נָבִ֥יא מֽוֹרֶה שֶּׁ֖קֶר ה֥וּא הַ/זָּנָֽב", "en": {"kjv": "Therefore the Lord will cut off from Israel head and tail, branch and rush, in one day.", "web": "Therefore Yahweh will cut off from Israel head and tail, palm branch and reed, in one day.", "bsb": "So the LORD will cut off Israel’s head and tail, both palm branch and reed in a single day.", "asv": "Therefore Jehovah will cut off from Israel head and tail, palm-branch and rush, in one day.", "ylt": "And Jehovah cutteth off from Israel head and tail, Branch and reed--the same day,", "dra": "And the Lord shall destroy out of Israel the head and the tail, him that bendeth down, and him that holdeth back, in one day.", "bbe": "For this cause the Lord took away from Israel head and tail, high and low, in one day.", "geneva": "Therefore will the Lord cut off from Israel head and taile, branche and rush in one day.", "wycliffe": "And the Lord schal leese fro Israel the heed and the tail; crokynge and bischrewynge, ether refreynynge, in o dai.", "rotherham": "Therefore hath Yahweh cut off from Israel—Head and tail Palm-top and rush, In one day.", "darby": "And Jehovah will cut off from Israel head and tail, palm-branch and rush, in one day:", "twenty": "", "jps": "The elder and the man of rank, he is the head; and the prophet that teacheth lies, he is the tail.", "acv": "Therefore Jehovah will cut off from Israel head and tail, palm-branch and rush, in one day.", "anderson": "", "haweis": "", "noyes": "Therefore shall Jehovah cut off from Israel the head and the tail, The palm-branch and the rush, in one day.", "webster": "Therefore the LORD will cut off from Israel head and tail, branch and rush, in one day.", "vulgate": "et disperdet Dominus ab Israhel caput et caudam incurvantem et refrenantem die una;", "brenton": "So the Lord took away from Israel the head and tail, great and small, in one day:"}}, {"v": 15, "ref": "9:15", "o": "וַ/יִּֽהְי֛וּ מְאַשְּׁרֵ֥י הָֽ/עָם הַ/זֶּ֖ה מַתְעִ֑ים וּ/מְאֻשָּׁרָ֖י/ו מְבֻלָּעִֽים", "en": {"kjv": "The ancient and honourable, he is the head; and the prophet that teacheth lies, he is the tail.", "web": "The elder and the honorable man is the head, and the prophet who teaches lies is the tail.", "bsb": "The head is the elder and honorable man, and the tail is the prophet who teaches lies.", "asv": "The elder and the honorable man, he is the head; and the prophet that teacheth lies, he is the tail.", "ylt": "Elder, and accepted of face, he is the head, Prophet, teacher of falsehood, he is the tail.", "dra": "The aged and honourable, he is the head: and the prophet that teacheth lies, he is the tail.", "bbe": "The man who is honoured and responsible is the head, and the prophet who gives false teaching is the tail.", "geneva": "The ancient and the honorable man, he is the head: and the prophet that teacheth lies, he is the taile.", "wycliffe": "An elde man and onourable, he is the heed, and a profete techynge a leesyng, he is the tail.", "rotherham": "The elder and favourite, he, is the head,—And the prophet teaching falsehood, he, is the tail;", "darby": "the ancient and honourable, he is the head; and the prophet that teacheth lies, he is the tail.", "twenty": "", "jps": "For they that lead this people cause them to err; and they that are led of them are destroyed.", "acv": "The elder and the honorable man, he is the head. And the prophet who teaches lies, he is the tail.", "anderson": "", "haweis": "", "noyes": "[The aged and the honorable are the head, And the prophet that speaketh falsehood is the tail.]", "webster": "The ancient and honorable, he [is] the head; and the prophet that teacheth lies, he [is] the tail.", "vulgate": "longevus et honorabilis ipse est caput et propheta docens mendacium ipse cauda est;", "brenton": "the old man, and them that respect persons, this is the head; and the prophet teaching unlawful things, he is the tail."}}, {"v": 16, "ref": "9:16", "o": "עַל כֵּ֨ן עַל בַּחוּרָ֜י/ו לֹֽא יִשְׂמַ֣ח אֲדֹנָ֗/י וְ/אֶת יְתֹמָ֤י/ו וְ/אֶת אַלְמְנֹתָי/ו֙ לֹ֣א יְרַחֵ֔ם כִּ֤י כֻלּ/וֹ֙ חָנֵ֣ף וּ/מֵרַ֔ע וְ/כָל פֶּ֖ה דֹּבֵ֣ר נְבָלָ֑ה בְּ/כָל זֹאת֙ לֹא שָׁ֣ב אַפּ֔/וֹ וְ/ע֖וֹד יָד֥/וֹ נְטוּיָֽה", "en": {"kjv": "For the leaders of this people cause them to err; and they that are led of them are destroyed.", "web": "For those who lead this people lead them astray; and those who are led by them are destroyed.", "bsb": "For those who guide this people mislead them, and those they mislead are swallowed up.", "asv": "For they that lead this people cause them to err; and they that are led of them are destroyed.", "ylt": "And the eulogists of this people are causing to err, And its eulogised ones are consumed.", "dra": "And they that call this people blessed, shall cause them to err: and they that are called blessed, shall be thrown down, headlong.", "bbe": "For the guides of this people are the cause of their wandering from the right way, and those who are guided by them come to destruction.", "geneva": "For the leaders of the people cause them to erre: and they that are led by them are deuoured.", "wycliffe": "And thei that blessen his puple, schulen be disseyueris, and thei that ben blessid, schulen be cast doun.", "rotherham": "And they who should have led this people forward have been causing them to stray,—And, they who are led of them are destroyed,", "darby": "For the guides of this people mislead [them]; and they that are guided by them are swallowed up.", "twenty": "", "jps": "Therefore the L-rd shall have no joy in their young men, neither shall He have compassion on their fatherless and widows; for every one is ungodly and an evil-doer, and every mouth speaketh wantonness. For all this His anger is not turned away, but His hand is stretched out still.", "acv": "For those who lead this people cause them to err, and those who are led by them are destroyed.", "anderson": "", "haweis": "", "noyes": "For the leaders of this people lead them astray, And they that are led by them go to destruction.", "webster": "For the leaders of this people cause [them] to err; and [they that are] led by them [are] destroyed.", "vulgate": "et erunt qui beatificant populum istum seducentes et qui beatificantur praecipitati;", "brenton": "And they that pronounce this people blessed shall mislead them; and they mislead them that they may devour them."}}, {"v": 17, "ref": "9:17", "o": "כִּֽי בָעֲרָ֤ה כָ/אֵשׁ֙ רִשְׁעָ֔ה שָׁמִ֥יר וָ/שַׁ֖יִת תֹּאכֵ֑ל וַ/תִּצַּת֙ בְּ/סִֽבְכֵ֣י הַ/יַּ֔עַר וַ/יִּֽתְאַבְּכ֖וּ גֵּא֥וּת עָשָֽׁן", "en": {"kjv": "Therefore the Lord shall have no joy in their young men, neither shall have mercy on their fatherless and widows: for every one is an hypocrite and an evildoer, and every mouth speaketh folly. For all this his anger is not turned away, but his hand is stretched out still.", "web": "Therefore the Lord will not rejoice over their young men, neither will he have compassion on their fatherless and widows; for everyone is profane and an evildoer, and every mouth speaks folly. For all this his anger is not turned away, but his hand is stretched out still.", "bsb": "Therefore the Lord takes no pleasure in their young men; He has no compassion on their fatherless and widows. For every one of them is godless and wicked, and every mouth speaks folly. Despite all this, His anger is not turned away; His hand is still upraised.", "asv": "Therefore the Lord will not rejoice over their young men, neither will he have compassion on their fatherless and widows; for every one is profane and an evil-doer, and every mouth speaketh folly. For all this his anger is not turned away, but his hand is stretched out still.", "ylt": "Therefore, over its young men the Lord rejoiceth not, And its orphans, and its widows He pitieth not, For every one is profane, and an evil doer, And every mouth is speaking folly. With all this not turned back hath His anger, And still His hand is stretched out.", "dra": "Therefore the Lord shall have no joy in their young men: neither shall he have mercy on their fatherless, and widows: for every one is a hypocrite and wicked, and every mouth hath spoken folly. For all this his indignation is not turned away, but his hand is stretched out still.", "bbe": "For this cause the Lord will have no pleasure in their young men, and no pity on their widows and the children without fathers: for they are all haters of God and evil-doers, and foolish words come from every mouth. For all this his wrath is not turned away, but his hand is stretched out still.", "geneva": "Therefore shall the Lord haue no pleasure in their yong men, neither will he haue compassion of their fatherlesse and of their widowes: for euery one is an hypocrite and wicked, and euery mouth speaketh follie: yet for all this his wrath is not turned away, but his hand is stretched out stil.", "wycliffe": "For this thing the Lord schal not be glad on the yonge men therof, and he schal not haue merci on the fadirles children and widewis therof; for ech man is an ypocrite and weiward, and ech mouth spak foli. In alle these thingis the stronge veniaunce of hym is not turned awei, but yit his hond is stretchid forth;", "rotherham": "For this cause, over their choice young men, will My Lord not rejoice, And on their fatherless and their widows, will he not have compassion, For every one of them, is profane and an evildoer, And, every mouth is speaking baseness,—For all this, hath his anger, not turned back, But still, is his hand outstretched.", "darby": "Therefore the Lord will not rejoice in their young men, neither will he have mercy on their fatherless and on their widows; for every one is a hypocrite and an evildoer, and every mouth speaketh folly. For all this his anger is not turned away, and his hand is stretched out still.", "twenty": "", "jps": "For wickedness burneth as the fire; it devoureth the briers and thorns; yea, it kindleth in the thickets of the forest, and they roll upward in thick clouds of smoke.", "acv": "Therefore the Lord will not rejoice over their young men, nor will he have compassion on their fatherless and widows. For everyone is profane and an evildoer, and every mouth speaks folly. For all this his anger is not turned away, but his hand is stretched out still.", "anderson": "", "haweis": "", "noyes": "Therefore shall the Lord have no joy in their young men, And on their orphans and widows he shall have no compassion; For they are all profane, and evil-doers; Every mouth speaketh folly. For all this his anger is not turned away, But his hand is stretched out still.", "webster": "Therefore the Lord will have no joy in their young men, neither will have mercy on their fatherless and widows: for every one [is] a hypocrite and an evil-doer, and every mouth speaketh folly. For all this his anger is not turned away, but his hand [is] stretched out still.", "vulgate": "propter hoc super adulescentulis eius non laetabitur Dominus et pupillorum eius et viduarum non miserebitur quia omnis hypocrita est et nequam et universum os locutum est stultitiam in omnibus his non est aversus furor eius sed adhuc manus eius extenta;", "brenton": "Therefore the Lord shall not take pleasure in their young men, neither shall he have pity on their orphans or on their widows: for they are all transgressors and wicked, and every mouth speaks unjustly. For all this his anger is not turned away, but his hand is yet exalted."}}, {"v": 18, "ref": "9:18", "o": "בְּ/עֶבְרַ֛ת יְהוָ֥ה צְבָא֖וֹת נֶעְתַּ֣ם אָ֑רֶץ וַ/יְהִ֤י הָ/עָם֙ כְּ/מַאֲכֹ֣לֶת אֵ֔שׁ אִ֥ישׁ אֶל אָחִ֖י/ו לֹ֥א יַחְמֹֽלוּ", "en": {"kjv": "For wickedness burneth as the fire: it shall devour the briers and thorns, and shall kindle in the thickets of the forest, and they shall mount up like the lifting up of smoke.", "web": "For wickedness burns like a fire. It devours the briers and thorns; yes, it kindles in the thickets of the forest, and they roll upward in a column of smoke.", "bsb": "For wickedness burns like a fire that consumes the thorns and briers and kindles the forest thickets which roll upward in billows of smoke.", "asv": "For wickedness burneth as the fire; it devoureth the briers and thorns; yea, it kindleth in the thickets of the forest, and they roll upward in a column of smoke.", "ylt": "For burned as a fire hath wickedness, Brier and thorn it devoureth, And it kindleth in thickets of the forest, And they lift themselves up, an exaltation of smoke!", "dra": "For wickedness is kindled as a fire, it shall devour the brier and the thorn: and shall kindle in the thicket of the forest, and it shall be wrapped up in smoke ascending on high.", "bbe": "For evil was burning like a fire; the blackberries and thorns were burned up; the thick woods took fire, rolling up in dark clouds of smoke.", "geneva": "For wickednesse burneth as a fire: it deuoureth the briers and the thornes and will kindle in the thicke places of the forest: and they shall mount vp like the lifting vp of smoke.", "wycliffe": "and the puple is not turned ayen to the Lord smytynge it. For whi wickidnesse is kyndlid as fier; it schal deuoure the breris and thornes, and it schal be kyndlid in the thickenesse of the forest, and it schal be wlappid togidere in the pride of smoke.", "rotherham": "For lawlessness, hath consumed like fire, Briars and thorns, doth it devour,—Yea it hath kindled upon the thickets of the forest, And they have rolled up as a column of smoke.", "darby": "For wickedness burneth as a fire: it devoureth briars and thorns, and kindleth in the thickets of the forest, and they go rolling up like a pillar of smoke.", "twenty": "", "jps": "Through the wrath of HaShem of hosts is the land burnt up; the people also are as the fuel of fire; no man spareth his brother.", "acv": "For wickedness burns as the fire. It devours the briers and thorns. Yea, it kindles in the thickets of the forest, and they roll upward in a column of smoke.", "anderson": "", "haweis": "", "noyes": "For wickedness burneth like a fire, It consumeth the briers and thorns, And it kindleth the thicket of the forest, So that it goeth up in columns of smoke.", "webster": "For wickedness burneth as the fire: it shall devour the briers and thorns, and shall kindle in the thickets of the forest, and they shall mount up [like] the rising of smoke.", "vulgate": "succensa est enim quasi ignis impietas veprem et spinam vorabit et succendetur in densitate saltus et convolvetur superbia fumi;", "brenton": "And iniquity shall burn as fire, and shall be devoured by fire as dry grass: and it shall burn in the thickets of the wood, and shall devour all that is round about the hills."}}, {"v": 19, "ref": "9:19", "o": "וַ/יִּגְזֹ֤ר עַל יָמִין֙ וְ/רָעֵ֔ב וַ/יֹּ֥אכַל עַל שְׂמֹ֖אול וְ/לֹ֣א שָׂבֵ֑עוּ אִ֥ישׁ בְּשַׂר זְרֹע֖/וֹ יֹאכֵֽלוּ", "en": {"kjv": "Through the wrath of the Lord of hosts is the land darkened, and the people shall be as the fuel of the fire: no man shall spare his brother.", "web": "Through the wrath of Yahweh of Armies, the land is burnt up; and the people are the fuel for the fire. No one spares his brother.", "bsb": "By the wrath of the LORD of Hosts the land is scorched, and the people are fuel for the fire. No man even spares his brother.", "asv": "Through the wrath of Jehovah of hosts is the land burnt up; and the people are as the fuel of fire: no man spareth his brother.", "ylt": "In the wrath of Jehovah of Hosts Hath the land been consumed, And the people is as fuel of fire; A man on his brother hath no pity,", "dra": "By the wrath of the Lord of hosts the land is troubled, and the people shall be as fuel for the fire: no man shall spare his brother.", "bbe": "The land was dark with the wrath of the Lord of armies: the people were like those who take men's flesh for food.", "geneva": "By the wrath of the Lord of hostes shall the land be darkened, and the people shall be as the meate of ye fire: no man shall spare his brother.", "wycliffe": "In the wraththe of the Lord of oostis the lond schal be disturblid, and the puple schal be as the mete of fier; a man schal not spare his brothir.", "rotherham": "Through the wrath of Yahweh of hosts, is the land consumed,—And the people have come to be, as fuel for fire, A man unto his own brother, sheweth not pity;", "darby": "Through the wrath of Jehovah of hosts is the land burned up, and the people is as fuel for fire: a man spareth not his brother;", "twenty": "", "jps": "And one snatcheth on the right hand, and is hungry; and he eateth on the left hand, and is not satisfied; they eat every man the flesh of his own arm:", "acv": "Through the wrath of Jehovah of hosts is the land burnt up, and the people are as the fuel of fire; no man spares his brother.", "anderson": "", "haweis": "", "noyes": "Through the wrath of Jehovah of hosts is the land burned, And the people are food for the fire; No one spareth another.", "webster": "Through the wrath of the LORD of hosts is the land darkened, and the people shall be as the fuel of the fire: no man shall spare his brother.", "vulgate": "in ira Domini exercituum conturbata est terra et erit populus quasi esca ignis vir fratri suo non parcet;", "brenton": "The whole earth is set on fire because of the fierce anger of the Lord, and the people shall be as men burnt by fire: no man shall pity his brother."}}, {"v": 20, "ref": "9:20", "o": "מְנַשֶּׁ֣ה אֶת אֶפְרַ֗יִם וְ/אֶפְרַ֨יִם֙ אֶת מְנַשֶּׁ֔ה יַחְדָּ֥ו הֵ֖מָּה עַל יְהוּדָ֑ה בְּ/כָל זֹאת֙ לֹא שָׁ֣ב אַפּ֔/וֹ וְ/ע֖וֹד יָד֥/וֹ נְטוּיָֽה", "en": {"kjv": "And he shall snatch on the right hand, and be hungry; and he shall eat on the left hand, and they shall not be satisfied: they shall eat every man the flesh of his own arm:", "web": "One will devour on the right hand, and be hungry; and he will eat on the left hand, and they will not be satisfied. Everyone will eat the flesh of his own arm:", "bsb": "They carve out what is on the right, but they are still hungry; they eat what is on the left, but they are still not satisfied. Each one devours the flesh of his own offspring.", "asv": "And one shall snatch on the right hand, and be hungry; and he shall eat on the left hand, and they shall not be satisfied: they shall eat every man the flesh of his own arm:", "ylt": "And cutteth down on the right, and hath been hungry, And he devoureth on the left, And they have not been satisfied, Each the flesh of his own arm they devour.", "dra": "And he shall turn to the right hand, and shall be hungry: and shall eat on the left hand, and shall not be filled: every one shall eat the flesh of his own arm: Manasses Ephraim, and Ephraim Manasses, and they together shall be against Juda.", "bbe": "On the right a man was cutting off bits and was still in need; on the left a man took a meal but had not enough; no man had pity on his brother; every man was making a meal of the flesh of his neighbour.", "geneva": "And he shall snatch at the right hand, and be hungrie: and he shall eate on the left hand, and shall not be satisfied: euery one shall eate ye flesh of his owne arme.", "wycliffe": "And he schal boowe to the riyt half, and he schal hungre, and he schal ete at the left half, and he schal not be fillid; ech man schal deuoure the fleisch of his arm. Manasses schal deuoure Effraym, and Effraym `schal deuoure Manasses, and thei togidere ayens Juda.", "rotherham": "And he hath slain on the right, and yet is hungry, And hath eaten on the left, yet are they not satisfied,—Every one, the flesh of his own arm, will they eat:", "darby": "and he snatcheth on the right hand, and is hungry, and eateth on the left hand; and they are not satisfied. They eat every man the flesh of his own arm:", "twenty": "", "jps": "Manasseh, Ephraim; and Ephraim, Manasseh; and they together are against Judah. For all this His anger is not turned away, but His hand is stretched out still.", "acv": "And he shall snatch on the right hand, and be hungry. And he shall eat on the left hand, and they shall not be satisfied. They shall eat every man the flesh of his own arm-", "anderson": "", "haweis": "", "noyes": "They consume on the right hand, and yet are hungry; They devour on the left, and are not satisfied; Every one devoureth the flesh of his arm.", "webster": "And he shall snatch on the right hand, and be hungry; and he shall eat on the left hand, and they shall not be satisfied: they shall eat every man the flesh of his own arm:", "vulgate": "et declinabit ad dexteram et esuriet et comedet ad sinistram et non saturabitur unusquisque carnem brachii sui vorabit Manasses Ephraim et Ephraim Manassen simul ipsi contra Iudam;", "brenton": "But one shall turn aside to the right hand, for he shall be hungry; and shall eat on the left, and a man shall by no means be satisfied with eating the flesh of his own arm."}}, {"v": 21, "ref": "9:21", "o": "", "en": {"kjv": "Manasseh, Ephraim; and Ephraim, Manasseh: and they together shall be against Judah. For all this his anger is not turned away, but his hand is stretched out still.", "web": "Manasseh, Ephraim; and Ephraim, Manasseh; and they together shall be against Judah. For all this his anger is not turned away, but his hand is stretched out still.", "bsb": "Manasseh devours Ephraim, and Ephraim Manasseh; together they turn against Judah. Despite all this, His anger is not turned away; His hand is still upraised.", "asv": "Manasseh, Ephraim; and Ephraim, Manasseh; and they together shall be against Judah. For all this his anger is not turned away, but his hand is stretched out still.", "ylt": "Manasseh--Ephraim, and Ephraim--Manasseh, Together they are against Judah, With all this not turned back hath His anger. And still His hand is stretched out!", "dra": "After all these things his indignation is not turned away, but his hand is stretched out still.", "bbe": "Manasseh was making a meal of Ephraim, and Ephraim of Manasseh; and together they were attacking Judah. For all this his wrath is not turned away, but his hand is stretched out still.", "geneva": "Manasseh, Ephraim: and Ephraim Manasseh, and they both shall be against Iudah yet for all this his wrath is not turned away, but his hand is stretched out still.", "wycliffe": "In alle these thingis the strong veniaunce of hym is not turned awei, but yit his hoond is stretchid forth.", "rotherham": "Manasseh—Ephraim, and Ephraim—Manasseh, They together—against Judah,—For all this, hath his anger not turned back, But still, is his hand outstretched.", "darby": "Manasseh, Ephraim, and Ephraim, Manasseh; [and] they together are against Judah. For all this his anger is not turned away, and his hand is stretched out still.", "twenty": "", "jps": "", "acv": "Manasseh, Ephraim, and Ephraim, Manasseh, and together they shall be against Judah. For all this his anger is not turned away, but his hand is stretched out still.", "anderson": "", "haweis": "", "noyes": "Manasseh is against Ephraim, and Ephraim against Manasseh, And both together against Judah. For all this his anger is not turned away, But his hand is stretched out still.", "webster": "Manasseh, Ephraim; and Ephraim, Manasseh: [and] they together [shall be] against Judah. For all this his anger is not turned away, but his hand [is] stretched out still.", "vulgate": "in omnibus his non est aversus furor eius sed adhuc manus eius extenta;", "brenton": "For Manasses shall eat the flesh of Ephraim, and Ephraim the flesh of Manasses; for they shall besiege Juda together. For all this his anger is not turned away, but his hand is yet exalted."}}]}, {"c": 10, "verses": [{"v": 1, "ref": "10:1", "o": "ה֥וֹי הַ/חֹֽקְקִ֖ים חִקְקֵי אָ֑וֶן וּֽ/מְכַתְּבִ֥ים עָמָ֖ל כִּתֵּֽבוּ", "en": {"kjv": "Woe unto them that decree unrighteous decrees, and that write grievousness which they have prescribed;", "web": "Woe to those who decree unrighteous decrees, and to the writers who write oppressive decrees;", "bsb": "Woe to those who enact unjust statutes and issue oppressive decrees,", "asv": "Woe unto them that decree unrighteous decrees, and to the writers that write perverseness;", "ylt": "Woe to those decreeing decrees of iniquity, And writers who have prescribed perverseness.", "dra": "Woe to them that make wicked laws: and when they write, write injustice:", "bbe": "Cursed are those who make evil decisions, and the writers who make the records of their cruel acts:", "geneva": "Woe vnto them that decree wicked decrees, and write grieuous things,", "wycliffe": "Wo to them that maken wickid lawis, and thei writynge han wryte vnriytfulnesse, for to oppresse pore men in doom,", "rotherham": "Alas! for them who ordain iniquitous decrees,—And, busy writers, who make a business of writing mischief:", "darby": "Woe unto them that decree iniquitous decrees, and to the writers that prescribe oppression,", "twenty": "", "jps": "Woe unto them that decree unrighteous decrees, and to the writers that write iniquity;", "acv": "Woe to those who decree unrighteous decrees, and to the writers who write perverseness,", "anderson": "", "haweis": "", "noyes": "Woe to them that make unrighteous decrees, That write oppressive decisions,", "webster": "Woe to them that decree unrighteous decrees, and that write grievousness [which] they have prescribed;", "vulgate": "vae qui condunt leges iniquas et scribentes iniustitiam scripserunt;", "brenton": "Woe to them that write wickedness; for when they write they do write wickedness,"}}, {"v": 2, "ref": "10:2", "o": "לְ/הַטּ֤וֹת מִ/דִּין֙ דַּלִּ֔ים וְ/לִ/גְזֹ֕ל מִשְׁפַּ֖ט עֲנִיֵּ֣י עַמִּ֑/י לִ/הְי֤וֹת אַלְמָנוֹת֙ שְׁלָלָ֔/ם וְ/אֶת יְתוֹמִ֖ים יָבֹֽזּוּ", "en": {"kjv": "To turn aside the needy from judgment, and to take away the right from the poor of my people, that widows may be their prey, and that they may rob the fatherless!", "web": "to deprive the needy from justice, and to rob the poor among my people of their rights, that widows may be their plunder, and that they may make the fatherless their prey!", "bsb": "to deprive the poor of fair treatment and withhold justice from the oppressed of My people, to make widows their prey and orphans their plunder.", "asv": "to turn aside the needy from justice, and to rob the poor of my people of their right, that widows may be their spoil, and that they may make the fatherless their prey!", "ylt": "To turn aside from judgment the poor, And to take violently away the judgment Of the afflicted of My people, That widows may be their prey, That the fatherless they may spoil.", "dra": "To oppress the poor in judgment, and do violence to the cause of the humble of my people: that widows might be their prey, and that they might rob the fatherless.", "bbe": "Who do wrong to the poor in their cause, and take away the right of the crushed among my people, so that they may have the property of widows, and get under their power those who have no father.", "geneva": "To keepe backe ye poore from iudgement, and to take away the iudgement of the poore of my people, that widowes may be their pray, and that they may spoyle the fatherlesse.", "wycliffe": "and to do violence to the cause of meke men of my puple; that widewis schulen be the prey of them, and that thei schulden rauysche fadirles children.", "rotherham": "Turning aside from judgment, the poor, And robbing, of justice, the oppressed of my people,—So that, widows, become, their spoil, And of the fatherless, they make prey.", "darby": "to turn away the poor from judgment, and to take away the right from the afflicted of my people; that widows may be their prey, and that they may rob the fatherless!", "twenty": "", "jps": "To turn aside the needy from judgment, and to take away the right of the poor of My people, that widows may be their spoil, and that they may make the fatherless their prey!", "acv": "to turn aside the needy from justice, and to rob the poor of my people of their right, that widows may be their spoil, and that they may make the fatherless their prey!", "anderson": "", "haweis": "", "noyes": "To turn away the needy from judgment, And rob the poor of my people of their right; That the widows may become their prey, And that they may plunder the orphans.", "webster": "To turn aside the needy from judgment, and to take away the right from the poor of my people, that widows may be their prey, and [that] they may rob the fatherless!", "vulgate": "ut opprimerent in iudicio pauperes et vim facerent causae humilium populi mei ut essent viduae praeda eorum et pupillos diriperent;", "brenton": "perverting the cause of the poor, violently wresting the judgment of the needy ones of my people, that the widow may be a prey to them, and the orphan a spoil."}}, {"v": 3, "ref": "10:3", "o": "וּ/מַֽה תַּעֲשׂוּ֙ לְ/י֣וֹם פְּקֻדָּ֔ה וּ/לְ/שׁוֹאָ֖ה מִ/מֶּרְחָ֣ק תָּב֑וֹא עַל מִי֙ תָּנ֣וּסוּ לְ/עֶזְרָ֔ה וְ/אָ֥נָה תַעַזְב֖וּ כְּבוֹדְ/כֶֽם", "en": {"kjv": "And what will ye do in the day of visitation, and in the desolation which shall come from far? to whom will ye flee for help? and where will ye leave your glory?", "web": "What will you do in the day of visitation, and in the desolation which will come from afar? To whom will you flee for help? Where will you leave your wealth?", "bsb": "What will you do on the day of reckoning when devastation comes from afar? To whom will you flee for help? Where will you leave your wealth?", "asv": "And what will ye do in the day of visitation, and in the desolation which shall come from far? to whom will ye flee for help? and where will ye leave your glory?", "ylt": "And what do ye at a day of inspection? And at desolation? --from afar it cometh. Near whom do ye flee for help? And where do ye leave your honour?", "dra": "What will you do in the day of visitation, and of the calamity which cometh from afar? to whom will ye flee for help? and where will ye leave your glory?", "bbe": "And what will you do in the day of punishment, and in the destruction which is coming from far? to whom will you go for help, and what will become of your glory?", "geneva": "What will ye doe nowe in the day of visitation, and of destruction, which shall come from farre? to whom will ye flee for helpe? and where will ye leaue your glorie?", "wycliffe": "What schulen ye do in the dai of visitacioun, and of wretchidnesse comynge fro fer? To whos help schulen ye fle? and where schulen ye leeue youre glorie,", "rotherham": "What, then, will ye do for the day of visitation, And for the devastation, which from afar, shall come? Unto whom, will ye flee for help? And where will ye leave your gory?", "darby": "And what will ye do in the day of visitation, and in the sudden destruction [which] shall come from far? To whom will ye flee for help, and where will ye leave your glory?", "twenty": "", "jps": "And what will ye do in the day of visitation, and in the ruin which shall come from far? To whom will ye flee for help? And where will ye leave your glory?", "acv": "And what will ye do in the day of visitation, and in the desolation which shall come from far? To whom will ye flee for help? And where will ye leave your glory?", "anderson": "", "haweis": "", "noyes": "What will ye do in the day of visitation, And in the desolation which cometh from afar? To whom will ye flee for help, And where will ye leave your glory?", "webster": "And what will ye do in the day of visitation, and in the desolation [which] shall come from far? to whom will ye flee for help? and where will ye leave your glory?", "vulgate": "quid facietis in die visitationis et calamitatis de longe venientis ad cuius fugietis auxilium et ubi derelinquetis gloriam vestram;", "brenton": "And what will they do in the day of visitation? for affliction shall come to you from afar: and to whom will ye flee for help? and where will ye leave your glory,"}}, {"v": 4, "ref": "10:4", "o": "בִּלְתִּ֤י כָרַע֙ תַּ֣חַת אַסִּ֔יר וְ/תַ֥חַת הֲרוּגִ֖ים יִפֹּ֑לוּ בְּ/כָל זֹאת֙ לֹא שָׁ֣ב אַפּ֔/וֹ וְ/ע֖וֹד יָד֥/וֹ נְטוּיָֽה", "en": {"kjv": "Without me they shall bow down under the prisoners, and they shall fall under the slain. For all this his anger is not turned away, but his hand is stretched out still.", "web": "They will only bow down under the prisoners, and will fall under the slain. For all this his anger is not turned away, but his hand is stretched out still.", "bsb": "Nothing will remain but to crouch among the captives or fall among the slain. Despite all this, His anger is not turned away; His hand is still upraised.", "asv": "They shall only bow down under the prisoners, and shall fall under the slain. For all this his anger is not turned away, but his hand is stretched out still.", "ylt": "Without Me it hath bowed down In the place of a bound one, And in the place of the slain they fall. With all this not turned back hath His anger, And still His hand is stretched out.", "dra": "That you be not bowed down under the bond, and fall with the slain? In all these things his anger is not turned away, but his hand is stretched out still.", "bbe": "... For all this his wrath is not turned away, but his hand is stretched out still.", "geneva": "Without me euery one shall fall among them that are bound, and they shall fall downe among the slayne: yet for all this his wrath is not turned away, but his hand is stretched out still.", "wycliffe": "that ye be not bowid doun vndur boond, and falle not doun with slayn men? On alle these thingis his strong veniaunce is not turned awei, but yit his hond is stretchid forth.", "rotherham": "Without me, one hath bowed under a prisoner Yea under the slain, do they fall! For all this, hath his anger, not turned back, But still, is his hand outstretched.", "darby": "They can but crouch under the prisoners, and they shall fall under the slain. For all this his anger is not turned away, and his hand is stretched out still.", "twenty": "", "jps": "They can do nought except crouch under the captives, and fall under the slain. For all this His anger is not turned away, but His hand is stretched out still.", "acv": "They shall only bow down under the prisoners, and shall fall under the slain. For all this his anger is not turned away, but his hand is stretched out still.", "anderson": "", "haweis": "", "noyes": "Forsaken by me, they shall sink down among the prisoners, And fall among the slain. For all this his anger is not turned away, But his hand is stretched out still.", "webster": "Without me they shall bow down under the prisoners, and they shall fall under the slain. For all this his anger is not turned away, but his hand [is] stretched out still.", "vulgate": "ne incurvemini sub vinculo et cum interfectis cadatis super omnibus his non est aversus furor eius sed adhuc manus eius extenta;", "brenton": "that ye may not fall into captivity? For all this his wrath is not turned away, but his hand is yet exalted."}}, {"v": 5, "ref": "10:5", "o": "ה֥וֹי אַשּׁ֖וּר שֵׁ֣בֶט אַפִּ֑/י וּ/מַטֶּה ה֥וּא בְ/יָדָ֖/ם זַעְמִֽ/י", "en": {"kjv": "O Assyrian, the rod of mine anger, and the staff in their hand is mine indignation.", "web": "Alas Assyrian, the rod of my anger, the staff in whose hand is my indignation!", "bsb": "Woe to Assyria, the rod of My anger; the staff in their hands is My wrath.", "asv": "Ho Assyrian, the rod of mine anger, the staff in whose hand is mine indignation!", "ylt": "Woe to Asshur, a rod of Mine anger, And a staff in their hand is Mine indignation.", "dra": "Woe to the Assyrian, he is the rod and the staff of my anger, and my indignation is in their hands.", "bbe": "Ho! Assyrian, the rod of my wrath, the instrument of my punishment!", "geneva": "O Asshur, the rodde of my wrath: and the staffe in their hands is mine indignation.", "wycliffe": "Wo to Assur, he is the yerde and staf of my strong veniaunce; myn indignacioun is in the hond of them.", "rotherham": "Alas! for Assyria, the rod of mine anger,—Yea, the very staff in their hand, is, my displeasure:", "darby": "Ah! the Assyrian! the rod of mine anger! and the staff in their hand is mine indignation.", "twenty": "", "jps": "O Asshur, the rod of Mine anger, in whose hand as a staff is Mine indignation!", "acv": "Ho, Assyrian, the rod of my anger, the staff in whose hand is my indignation!", "anderson": "", "haweis": "", "noyes": "Woe to the Assyrian, the rod of mine anger, The staff in whose hands is the instrument of my indignation!", "webster": "O Assyrian, the rod of my anger, and the staff in their hand is my indignation.", "vulgate": "vae Assur virga furoris mei et baculus ipse in manu eorum indignatio mea;", "brenton": "Woe to the Assyrians; the rod of my wrath, and anger are in their hands."}}, {"v": 6, "ref": "10:6", "o": "בְּ/ג֤וֹי חָנֵף֙ אֲשַׁלְּחֶ֔/נּוּ וְ/עַל עַ֥ם עֶבְרָתִ֖/י אֲצַוֶּ֑/נּוּ לִ/שְׁלֹ֤ל שָׁלָל֙ וְ/לָ/בֹ֣ז בַּ֔ז ו/ל/שימ/ו וּ/לְ/שׂוּמ֥/וֹ מִרְמָ֖ס כְּ/חֹ֥מֶר חוּצֽוֹת", "en": {"kjv": "I will send him against an hypocritical nation, and against the people of my wrath will I give him a charge, to take the spoil, and to take the prey, and to tread them down like the mire of the streets.", "web": "I will send him against a profane nation, and against the people who anger me will I give him a command to take the plunder and to take the prey, and to tread them down like the mire of the streets.", "bsb": "I will send him against a godless nation; I will dispatch him against a people destined for My rage, to take spoils and seize plunder, and to trample them down like clay in the streets.", "asv": "I will send him against a profane nation, and against the people of my wrath will I give him a charge, to take the spoil, and to take the prey, and to tread them down like the mire of the streets.", "ylt": "Against a profane nation I send him, And concerning a people of My wrath I charge him, To spoil spoil, and to seize prey, And to make it a treading-place as the clay of out places.", "dra": "I will send him to a deceitful nation, and I will give him a charge against the people of my wrath, to take away the spoils, and to lay hold on the prey, and to tread them down like the mire of the streets.", "bbe": "I will send him against a nation of wrongdoers, and against the people of my wrath I will give him orders, to take their wealth in war, crushing them down like the dust in the streets.", "geneva": "I will sende him to a dissembling nation, and I will giue him a charge against the people of my wrath to take the spoyle and to take the pray, and to treade them vnder feete like the mire in the streete.", "wycliffe": "Y schal send hym to a fals folk, and Y schal comaunde to hym ayens the puple of my strong veniaunce; that he take awei the spuylis, and departe prey, and that he sette that puple in to defouling, as the fen of stretis.", "rotherham": "Against an irreligious nation, will I send him, Yea against the people with whom I am wroth, will I command him,—To capture spoil And lay hold on prey, And cause them to be trodden down as the mire of the lanes.", "darby": "I will send him against a hypocritical nation, and against the people of my wrath will I give him a charge; to take the spoil, and to seize the prey, and to tread them down like the mire of the streets.", "twenty": "", "jps": "I do send him against an ungodly nation, and against the people of My wrath do I give him a charge, to take the spoil, and to take the prey, and to tread them down like the mire of the streets.", "acv": "I will send him against a profane nation, and against the people of my wrath. I will give him a charge, to take the spoil, and to take the prey, and to tread them down like the mire of the streets.", "anderson": "", "haweis": "", "noyes": "Against an impious nation I will send him, And against a people under my wrath I will give him a charge To gather the spoil, and seize the prey, And to trample them under foot like the mire of the streets.", "webster": "I will send him against a hypocritical nation, and against the people of my wrath will I give him a charge, to take the spoil, and to take the prey, and to tread them down like the mire of the streets.", "vulgate": "ad gentem fallacem mittam eum et contra populum furoris mei mandabo illi ut auferat spolia et diripiat praedam et ponat illum in conculcationem quasi lutum platearum;", "brenton": "I will send my wrath against a sinful nation, and I will charge my people to take plunder and spoil, and to trample the cities, and to make them dust."}}, {"v": 7, "ref": "10:7", "o": "וְ/הוּא֙ לֹא כֵ֣ן יְדַמֶּ֔ה וּ/לְבָב֖/וֹ לֹא כֵ֣ן יַחְשֹׁ֑ב כִּ֚י לְ/הַשְׁמִ֣יד בִּ/לְבָב֔/וֹ וּ/לְ/הַכְרִ֥ית גּוֹיִ֖ם לֹ֥א מְעָֽט", "en": {"kjv": "Howbeit he meaneth not so, neither doth his heart think so; but it is in his heart to destroy and cut off nations not a few.", "web": "However he doesn’t mean so, neither does his heart think so; but it is in his heart to destroy, and to cut off not a few nations.", "bsb": "But this is not his intention; this is not his plan. For it is in his heart to destroy and cut off many nations.", "asv": "Howbeit he meaneth not so, neither doth his heart think so; but it is in his heart to destroy, and to cut off nations not a few.", "ylt": "And he--he thinketh not so, And his heart reckoneth not so, For--to destroy is in his heart, And to cut off nations not a few.", "dra": "But he shall not take it so, and his heart shall not think so: but his heart shall be set to destroy, and to cut off nations not a few.", "bbe": "But this is not what is in his mind, and this is not his design; but his purpose is destruction, and the cutting off of more and more nations.", "geneva": "But he thinketh not so, neither doeth his heart esteeme it so: but he imagineth to destroy and to cut off not a fewe nations.", "wycliffe": "Forsothe he schal not deme so, and his herte schal not gesse so, but his herte schal be for to al to-breke, and to the sleynge of many folkis.", "rotherham": "But as for him, not so, doth he deem, And in his heart, not so, doth he think,—For, to destroy, is in his heart, And to cut off nations, not a few;", "darby": "But he meaneth not so, neither doth his heart think so; for it is in his heart to extirpate and cut off nations not a few.", "twenty": "", "jps": "Howbeit he meaneth not so, neither doth his heart think so; but it is in his heart to destroy, and to cut off nations not a few.", "acv": "However he does not so reason, nor does his heart so think, but it is in his heart to destroy, and to cut off nations not a few.", "anderson": "", "haweis": "", "noyes": "But he doth not so purpose, And his heart doth not so intend; But to destroy is in his heart, And to cut off a multitude of nations.", "webster": "Howbeit he meaneth not so, neither doth his heart think so; but [it is] in his heart to destroy and cut off nations not a few.", "vulgate": "ipse autem non sic arbitrabitur et cor eius non ita aestimabit sed ad conterendum erit cor eius et ad internicionem gentium non paucarum;", "brenton": "But he meant not thus, neither did he devise thus in his soul: but his mind shall change, and that to destroy nations not a few."}}, {"v": 8, "ref": "10:8", "o": "כִּ֖י יֹאמַ֑ר הֲ/לֹ֥א שָׂרַ֛/י יַחְדָּ֖ו מְלָכִֽים", "en": {"kjv": "For he saith, Are not my princes altogether kings?", "web": "For he says, “Aren’t all of my princes kings?", "bsb": "“Are not all my commanders kings?” he says.", "asv": "For he saith, Are not my princes all of them kings?", "ylt": "For he saith, `Are not my princes altogether kings?", "dra": "For he shall say:", "bbe": "For he says, Are not all my captains kings?", "geneva": "For he sayeth, Are not my princes altogether Kings?", "wycliffe": "For he schal seie, Whether my princes ben not kyngis to gidere?", "rotherham": "For he saith:—Are not, my generals, all alike, kings?", "darby": "For he saith, Are not my princes all kings?", "twenty": "", "jps": "For he saith: 'Are not my princes all of them kings?", "acv": "For he says, Are not my rulers all of them kings?", "anderson": "", "haweis": "", "noyes": "For he saith, \"Are not my princes altogether kings?", "webster": "For he saith, [Are] not my princes altogether kings?", "vulgate": "dicet enim;", "brenton": "And if they should say to him, Thou alone art ruler;"}}, {"v": 9, "ref": "10:9", "o": "הֲ/לֹ֥א כְּ/כַרְכְּמִ֖ישׁ כַּלְנ֑וֹ אִם לֹ֤א כְ/אַרְפַּד֙ חֲמָ֔ת אִם לֹ֥א כְ/דַמֶּ֖שֶׂק שֹׁמְרֽוֹן", "en": {"kjv": "Is not Calno as Carchemish? is not Hamath as Arpad? is not Samaria as Damascus?", "web": "Isn’t Calno like Carchemish? Isn’t Hamath like Arpad? Isn’t Samaria like Damascus?”", "bsb": "“Is not Calno like Carchemish? Is not Hamath like Arpad? Is not Samaria like Damascus?", "asv": "Is not Calno as Carchemish? is not Hamath as Arpad? is not Samaria as Damascus?", "ylt": "Is not Calno as Carchemish? Is not Hamath as Arpad? Is not Samaria as Damascus?", "dra": "Are not my princes as so many kings? is not Calano as Charcamis: and Emath as Arphad? is not Samaria as Damascus?", "bbe": "Will not the fate of Calno be like that of Carchemish? is not Hamath as Arpad? is not Samaria as Damascus?", "geneva": "Is not Calno as Carchemish? Is not Hamath like Arpad? Is not Samaria as Damascus?", "wycliffe": "Whether not as Carcamys, so Calanno; and as Arphat, so Emath? whether not as Damask, so Samarie?", "rotherham": "Is not, Calno, like Carchemish? Is not, Hamath, like Arpad? Is not, Samaria, like Damascus?", "darby": "Is not Calno as Karkemish? Is not Hamath as Arpad? Is not Samaria as Damascus?", "twenty": "", "jps": "Is not Calno as Carchemish? Is not Hamath as Arpad? Is not Samaria as Damascus?", "acv": "Is not Calno as Carchemish? Is not Hamath as Arpad? Is not Samaria as Damascus?", "anderson": "", "haweis": "", "noyes": "Is not Calno as Carchemish? Is not Hamath as Arpad? Is not Samaria as Damascus?", "webster": "[Is] not Calno as Carchemish? [is] not Hamath as Arpad? [is] not Samaria as Damascus?", "vulgate": "numquid non principes mei simul reges sunt numquid non ut Charchamis sic Chalanno et ut Arfad sic Emath numquid non ut Damascus sic Samaria;", "brenton": "then shall he say, Have I not taken the country above Babylon and Chalanes, where the tower was built? and have I not taken Arabia, and Damascus, and Samaria?"}}, {"v": 10, "ref": "10:10", "o": "כַּ/אֲשֶׁר֙ מָצְאָ֣ה יָדִ֔/י לְ/מַמְלְכֹ֖ת הָ/אֱלִ֑יל וּ/פְסִ֣ילֵי/הֶ֔ם מִ/ירֽוּשָׁלִַ֖ם וּ/מִ/שֹּׁמְרֽוֹן", "en": {"kjv": "As my hand hath found the kingdoms of the idols, and whose graven images did excel them of Jerusalem and of Samaria;", "web": "As my hand has found the kingdoms of the idols, whose engraved images exceeded those of Jerusalem and of Samaria;", "bsb": "As my hand seized the idolatrous kingdoms whose images surpassed those of Jerusalem and Samaria,", "asv": "As my hand hath found the kingdoms of the idols, whose graven images did excel them of Jerusalem and of Samaria;", "ylt": "As my hand hath got to the kingdoms of a worthless thing, and their graven images, Greater than Jerusalem and than Samaria,", "dra": "As my hand hath found the kingdoms of the idol, so also their idols of Jerusalem, and of Samaria.", "bbe": "As my hand has come on the kingdoms of the images, whose pictured images were more in number than those of Jerusalem and Samaria;", "geneva": "Like as mine hand hath founde the kingdomes of the idoles, seeing their idoles were aboue Ierusalem, and aboue Samaria:", "wycliffe": "As myn hond foond the rewmes of idol, so and the symylacris of hem of Jerusalem and of Samarie.", "rotherham": "As my hand hath reached unto the kingdoms of idols,—whose images did excel them of Jerusalem and Samaria,", "darby": "As my hand hath found the kingdoms of the idols, — and their graven images exceeded those of Jerusalem and Samaria,", "twenty": "", "jps": "As my hand hath reached the kingdoms of the idols, whose graven images did exceed them of Jerusalem and of Samaria;", "acv": "As my hand has found the kingdoms of the idols, whose graven images excelled those of Jerusalem and of Samaria,", "anderson": "", "haweis": "", "noyes": "As my hand hath seized the kingdoms of the idols, Whose graven images were more numerous than those of Jerusalem and Samaria,", "webster": "As my hand hath found the kingdoms of the idols, and whose graven images excelled them of Jerusalem and of Samaria;", "vulgate": "quomodo invenit manus mea regna idoli sic et simulacra eorum de Hierusalem et de Samaria;", "brenton": "As I have taken them, I will also take all the kingdoms: howl, ye idols in Jerusalem, and in Samaria."}}, {"v": 11, "ref": "10:11", "o": "הֲ/לֹ֗א כַּ/אֲשֶׁ֥ר עָשִׂ֛יתִי לְ/שֹׁמְר֖וֹן וְ/לֶ/אֱלִילֶ֑י/הָ כֵּ֛ן אֶעֱשֶׂ֥ה לִ/ירוּשָׁלִַ֖ם וְ/לַ/עֲצַבֶּֽי/הָ", "en": {"kjv": "Shall I not, as I have done unto Samaria and her idols, so do to Jerusalem and her idols?", "web": "shall I not, as I have done to Samaria and her idols, so do to Jerusalem and her idols?", "bsb": "and as I have done to Samaria and its idols, will I not also do to Jerusalem and her idols?”", "asv": "shall I not, as I have done unto Samaria and her idols, so do to Jerusalem and her idols?", "ylt": "Do I not--as I have done to Samaria, And to her worthless things, So do to Jerusalem and to her grievous things?", "dra": "Shall I not, as I have done to Samaria and her idols, so do to Jerusalem and her idols?", "bbe": "So, as I have done to Samaria and her images, I will do to Jerusalem and her images.", "geneva": "Shall not I, as I haue done to Samaria, and to the idoles thereof, so doe to Ierusalem and to the idoles thereof?", "wycliffe": "Whether not as Y dide to Samarie, and to the idols therof, so Y schal do to Jerusalem, and to the simylacris therof?", "rotherham": "Shall I not as I have done to Samaria and her idols, so, do to Jerusalem and her images?", "darby": "— shall I not, as I have done unto Samaria and her idols, so do to Jerusalem and her images?", "twenty": "", "jps": "Shall I not, as I have done unto Samaria and her idols, so do to Jerusalem and her idols?'", "acv": "shall I not, as I have done to Samaria and her idols, so do to Jerusalem and her idols?", "anderson": "", "haweis": "", "noyes": "Behold! as I have done to Samaria and her idols, So will I do to Jerusalem and her images.\"", "webster": "Shall I not, as I have done to Samaria and her idols, so do to Jerusalem and her idols?", "vulgate": "numquid non sicut feci Samariae et idolis eius sic faciam Hierusalem et simulacris eius;", "brenton": "For as I did to Samaria and her idols, so will I do also to Jerusalem and her idols."}}, {"v": 12, "ref": "10:12", "o": "וְ/הָיָ֗ה כִּֽי יְבַצַּ֤ע אֲדֹנָ/י֙ אֶת כָּל מַֽעֲשֵׂ֔/הוּ בְּ/הַ֥ר צִיּ֖וֹן וּ/בִ/ירוּשָׁלִָ֑ם אֶפְקֹ֗ד עַל פְּרִי גֹ֨דֶל֙ לְבַ֣ב מֶֽלֶךְ אַשּׁ֔וּר וְ/עַל תִּפְאֶ֖רֶת ר֥וּם עֵינָֽי/ו", "en": {"kjv": "Wherefore it shall come to pass, that when the Lord hath performed his whole work upon mount Zion and on Jerusalem, I will punish the fruit of the stout heart of the king of Assyria, and the glory of his high looks.", "web": "Therefore it will happen that, when the Lord has performed his whole work on Mount Zion and on Jerusalem, I will punish the fruit of the willful proud heart of the king of Assyria, and the insolence of his haughty looks.", "bsb": "So when the Lord has completed all His work against Mount Zion and Jerusalem, He will say, “I will punish the king of Assyria for the fruit of his arrogant heart and the proud look in his eyes.", "asv": "Wherefore it shall come to pass, that, when the Lord hath performed his whole work upon mount Zion and on Jerusalem, I will punish the fruit of the stout heart of the king of Assyria, and the glory of his high looks.", "ylt": "And it hath come to pass, When the Lord doth fulfil all His work In mount Zion and in Jerusalem, I see concerning the fruit of the greatness Of the heart of the king of Asshur. And concerning the glory of the height of his eyes.", "dra": "And it shall come to pass, that when the Lord shall have performed all his works in mount Sion, and in Jerusalem, I will visit the fruit of the proud heart of the king of Assyria, and the glory of the haughtiness of his eyes.", "bbe": "For this cause it will be that, when the purpose of the Lord against Mount Zion and Jerusalem is complete, I will send punishment on the pride of the heart of the king of Assyria, and on the glory of his uplifted eyes.", "geneva": "But when the Lord hath accomplished all his worke vpon mount Zion and Ierusalem, I will visite the fruite of the proude heart of the King of Asshur, and his glorious and proud lookes,", "wycliffe": "And it schal be, whanne the Lord hath fillid alle hise werkis in the hil of Syon and in Jerusalem, Y schal visite on the fruit of the greet doynge herte of the kyng of Assur, and on the glorie of the hiynesse of hise iyen.", "rotherham": "Wherefore it shall come to pass—When My Lord shall finish his whole work upon Mount Zion and upon Jerusalem, I will bring punishment—Upon the fruit of the greatness of heart of the king of Assyria. And upon the vainglory of his uplifted eyes,", "darby": "And it shall come to pass, when the Lord hath performed his whole work upon mount Zion and upon Jerusalem, I will punish the fruit of the stoutness of heart of the king of Assyria, and the glory of his high looks.", "twenty": "", "jps": "Wherefore it shall come to pass, that when the L-rd hath performed His whole work upon mount Zion and on Jerusalem, I will punish the fruit of the arrogant heart of the king of Assyria, and the glory of his haughty looks.", "acv": "Therefore it shall come to pass, that, when the Lord has performed his whole work upon mount Zion and on Jerusalem, I will punish the fruit of the arrogant heart of the king of Assyria, and the glory of his high looks.", "anderson": "", "haweis": "", "noyes": "But when the Lord hath accomplished his whole work upon Mount Zion and Jerusalem, Then will he punish the fruit of the proud heart of the king of Assyria, And the arrogance of his lofty eyes.", "webster": "Wherefore it shall come to pass, [that] when the Lord hath performed his whole work upon mount Zion and on Jerusalem, I will punish the fruit of the stout heart of the king of Assyria, and the glory of his high looks.", "vulgate": "et erit cum impleverit Dominus cuncta opera sua in monte Sion et in Hierusalem visitabo super fructum magnifici cordis regis Assur et super gloriam altitudinis oculorum eius;", "brenton": "And it shall come to pass, when the Lord shall have finished doing all things on Mount Sion and Jerusalem, that I will visit upon the proud heart, even upon the ruler of the Assyrians, and upon the boastful haughtiness of his eyes."}}, {"v": 13, "ref": "10:13", "o": "כִּ֣י אָמַ֗ר בְּ/כֹ֤חַ יָדִ/י֙ עָשִׂ֔יתִי וּ/בְ/חָכְמָתִ֖/י כִּ֣י נְבֻנ֑וֹתִי וְ/אָסִ֣יר גְּבוּלֹ֣ת עַמִּ֗ים ו/עתידתי/הם וַ/עֲתוּדֽוֹתֵי/הֶם֙ שׁוֹשֵׂ֔תִי וְ/אוֹרִ֥יד כַּ/אבִּ֖יר יוֹשְׁבִֽים", "en": {"kjv": "For he saith, By the strength of my hand I have done it, and by my wisdom; for I am prudent: and I have removed the bounds of the people, and have robbed their treasures, and I have put down the inhabitants like a valiant man:", "web": "For he has said, “By the strength of my hand I have done it, and by my wisdom; for I have understanding: and I have removed the boundaries of the peoples, and have robbed their treasures. Like a valiant man I have brought down their rulers.", "bsb": "For he says: ‘By the strength of my hand I have done this, and by my wisdom, for I am clever. I have removed the boundaries of nations and plundered their treasures; like a mighty one I subdued their rulers.", "asv": "For he hath said, By the strength of my hand I have done it, and by my wisdom; for I have understanding: and I have removed the bounds of the peoples, and have robbed their treasures, and like a valiant man I have brought down them that sit on thrones:", "ylt": "For he hath said, `By the power of my hand I have wrought, And by my wisdom, for I have been intelligent, And I remove borders of the peoples, And their chief ones I have spoiled, And I put down as a mighty one the inhabitants,", "dra": "For he hath said: By the strength of my own hand I have done it, and by my own wisdom I have understood: and I have removed the bounds of the people, and have taken the spoils of the princes, and as a mighty man hath pulled down them that sat on high.", "bbe": "For he has said, By the strength of my hand I have done it, and by my knowledge, for I am wise: and I have taken away the limits of the peoples' lands, and the stores of their wealth have become mine; and I have made towns low in the dust, sending destruction on those living in them;", "geneva": "Because he said, By ye power of mine owne hand haue I done it, and by my wisdome, because I am wise: therefore I haue remooued the borders of the people, and haue spoyled their treasures, and haue pulled downe the inhabitants like a valiant man.", "wycliffe": "For he seide, Y haue do in the strengthe of myn honde, and Y haue understonde in my wisdom; and Y haue take awei the endis of peplis, and Y haue robbid the princes of them, and Y as a myyti man haue drawun doun them that saten an hiy.", "rotherham": "For he hath said—By the strength of mine own hand, have I effectually wrought, And by my wisdom—for I have discernment,—That I might remove the bounds of peoples, Yea their treasures, have I plundered That I might lay prostrate as a mighty one the inhabitants;", "darby": "For he saith, By the strength of my hand I have done [it], and by my wisdom, for I am intelligent; and I have removed the bounds of the peoples, and have robbed their treasures, and, like a valiant man, I have brought down them that sit [on thrones];", "twenty": "", "jps": "For he hath said: by the strength of my hand I have done it, and by my wisdom, for I am prudent; in that I have removed the bounds of the peoples, and have robbed their treasures, and have brought down as one mighty the inhabitants;", "acv": "For he has said, By the strength of my hand I have done it, and by my wisdom, for I have understanding. And I have removed the bounds of the peoples, and have robbed their treasures. And like a valiant man I have brought down those who sit on thrones.", "anderson": "", "haweis": "", "noyes": "For he hath said: \"By the strength of my hand I have done it, And by my wisdom; for I am wise; I have removed the bounds of nations, I have plundered their treasures; As a hero have I brought down them that sat upon thrones.", "webster": "For he saith, By the strength of my hand I have done [it], and by my wisdom; for I am prudent: and I have removed the bounds of the people, and have robbed their treasures, and I have put down the inhabitants like a valiant [man]:", "vulgate": "dixit enim in fortitudine manus meae feci et in sapientia mea intellexi et abstuli terminos populorum et principes eorum depraedatus sum et detraxi quasi potens in sublime residentes;", "brenton": "For he said, I will act in strength, and in the wisdom of my understanding I will remove the boundaries of nations, and will spoil their strength."}}, {"v": 14, "ref": "10:14", "o": "וַ/תִּמְצָ֨א כַ/קֵּ֤ן יָדִ/י֙ לְ/חֵ֣יל הָֽ/עַמִּ֔ים וְ/כֶ/אֱסֹף֙ בֵּיצִ֣ים עֲזֻב֔וֹת כָּל הָ/אָ֖רֶץ אֲנִ֣י אָסָ֑פְתִּי וְ/לֹ֤א הָיָה֙ נֹדֵ֣ד כָּנָ֔ף וּ/פֹצֶ֥ה פֶ֖ה וּ/מְצַפְצֵֽף", "en": {"kjv": "And my hand hath found as a nest the riches of the people: and as one gathereth eggs that are left, have I gathered all the earth; and there was none that moved the wing, or opened the mouth, or peeped.", "web": "My hand has found the riches of the peoples like a nest, and like one gathers eggs that are abandoned, have I gathered all the earth. There was no one who moved their wing, or that opened their mouth, or chirped.”", "bsb": "My hand reached as into a nest to seize the wealth of the nations. Like one gathering abandoned eggs, I gathered all the earth. No wing fluttered, no beak opened or chirped.’”", "asv": "and my hand hath found as a nest the riches of the peoples; and as one gathereth eggs that are forsaken, have I gathered all the earth: and there was none that moved the wing, or that opened the mouth, or chirped.", "ylt": "And my hand as to a nest Getteth to the wealth of the peoples, And as a gathering of forsaken eggs All the earth I--I have gathered, And there hath not been one moving wing, Or opening mouth, or whispering.'", "dra": "And my hand hath found the strength of the people as a nest; and as eggs are gathered, that are left, so have I gathered all the earth: and there was none that moved the wing, or opened the mouth, or made the least noise.", "bbe": "And I have put my hands on the wealth of the peoples, as on the place where a bird has put her eggs; and as a man may take the eggs from which a bird has gone, so I have taken all the earth for myself: and not a wing was moved, and not a mouth gave out a sound.", "geneva": "And mine hand hath found as a nest the riches of the people, and as one gathereth egges that are left, so haue I gathered all the earth: and there was none to mooue the wing or to open the mouth, or to whisper.", "wycliffe": "And myn hond foond the strengthe of puplis as a nest, and as eirun ben gaderid togidere that ben forsakun, so Y gaderid togidere al erthe; and noon was that mouyde a fethere, and openyde the mouth, and grutchide.", "rotherham": "And my hand hath found as a nest the wealth of the peoples, And as the gathering of eggs that are forsaken, all the earth, have, I, gathered,—And there was none to flap a wing, or open a mouth or chirp.", "darby": "and my hand hath found as a nest the riches of the peoples, and as one gathereth forsaken eggs, have I gathered all the earth; and there was none that moved the wing, or opened the mouth, or chirped.", "twenty": "", "jps": "And my hand hath found as a nest the riches of the peoples; and as one gathereth eggs that are forsaken, have I gathered all the earth; and there was none that moved the wing, or that opened mouth, or chirped.", "acv": "And my hand has found as a nest the riches of the peoples. And like a gathering of eggs that are forsaken, I have gathered all the earth. And there was none that moved the wing, or that opened the mouth, or chirped.", "anderson": "", "haweis": "", "noyes": "The riches of the nations hath my hand seized, as a nest; As one gathereth eggs that have been left, So have I gathered the whole world. And there was none that moved the wing, Or that opened the beak, or that chirped.\"", "webster": "And my hand hath found as a nest the riches of the people: and as one gathereth eggs [that are] left, have I gathered all the earth; and there was none that moved the wing, or opened the mouth, or peeped.", "vulgate": "et invenit quasi nidum manus mea fortitudinem populorum et sicut colliguntur ova quae derelicta sunt sic universam terram ego congregavi et non fuit qui moveret pinnam et aperiret os et ganniret;", "brenton": "And I will shake the inhabited cities: and I will take with my hand all the world as a nest: and I will even take them as eggs that have been left; and there is none that shall escape me, or contradict me."}}, {"v": 15, "ref": "10:15", "o": "הֲ/יִתְפָּאֵר֙ הַ/גַּרְזֶ֔ן עַ֖ל הַ/חֹצֵ֣ב בּ֑/וֹ אִם יִתְגַּדֵּ֤ל הַ/מַּשּׂוֹר֙ עַל מְנִיפ֔/וֹ כְּ/הָנִ֥יף שֵׁ֨בֶט֙ וְ/אֶת מְרִימָ֔י/ו כְּ/הָרִ֥ים מַטֶּ֖ה לֹא עֵֽץ", "en": {"kjv": "Shall the axe boast itself against him that heweth therewith? or shall the saw magnify itself against him that shaketh it? as if the rod should shake itself against them that lift it up, or as if the staff should lift up itself, as if it were no wood.", "web": "Should an ax brag against him who chops with it? Should a saw exalt itself above him who saws with it? As if a rod should lift those who lift it up, or as if a staff should lift up someone who is not wood.", "bsb": "Does an axe raise itself above the one who swings it? Does a saw boast over him who saws with it? It would be like a rod waving the one who lifts it, or a staff lifting him who is not wood!", "asv": "Shall the axe boast itself against him that heweth therewith? shall the saw magnify itself against him that wieldeth it? as if a rod should wield them that lift it up, or as if a staff should lift up him that is not wood.", "ylt": "--Doth the axe glorify itself Against him who is hewing with it? Doth the saw magnify itself Against him who is shaking it? As a rod waving those lifting it up! As a staff lifting up that which is not wood!", "dra": "Shall the axe boast itself against him that cutteth with it? or shall the saw exalt itself against him by whom it is drawn? as if a rod should lift itself up against him that lifteth it up, and a staff exalt itself, which is but wood.", "bbe": "Will the axe say high-sounding words against him who is using it, or the blade be full of pride against him who is cutting with it? As if a rod had the power of shaking him who is using it, or as if a stick might take up him who is not wood.", "geneva": "Shall the axe boast it selfe against him that heweth therewith? or shall the sawe exalt it selfe against him that moueth it? as if the rod shoulde lift vp it selfe against him that taketh it vp, or the staffe should exalt it selfe, as it were no wood.", "wycliffe": "Whether an ax schal haue glorie ayens hym that kittith with it? ether a sawe schal be enhaunsid ayens hym of whom it is drawun? as if a yerde is reisid ayens hym that reisith it, and a staf is enhaunsid, which sotheli is a tre.", "rotherham": "Shall the axe boast itself against him that heweth therewith? Or, the saw, magnify itself, against him that wieldeth it? As if a rod, could wield, them who lift it up! As if a staff, could raise, what is, not wood!", "darby": "— Shall the axe boast itself against him that heweth therewith? shall the saw magnify itself against him that wieldeth it? As if the rod should wield them that lift it up; as if the staff should lift up [him who is] not wood!", "twenty": "", "jps": "Should the axe boast itself against him that heweth therewith? Should the saw magnify itself against him that moveth it? as if a rod should move them that lift it up, or as if a staff should lift up him that is not wood.", "acv": "Shall the axe boast itself against him who hews with it? Shall the saw magnify itself against him who wields it? As if a rod should wield those who lift it up, or as if a staff should lift up him who is not wood.", "anderson": "", "haweis": "", "noyes": "Shall the axe boast itself against him that heweth with it? Or shall the saw magnify itself against him that moveth it? As if the rod should wield him that lifteth it! As if the staff should lift up him that is not wood!", "webster": "Shall the ax boast itself against him that heweth with it? [or] shall the saw magnify itself against him that moveth it? as if the rod should shake [itself] against them that lift it, [or] as if the staff should lift [itself], [as if it were] no wood.", "vulgate": "numquid gloriabitur securis contra eum qui secat in ea aut exaltabitur serra contra eum a quo trahitur quomodo si elevetur virga contra levantem se et exaltetur baculus qui utique lignum est;", "brenton": "Shall the axe glorify itself without him that hews with it? or shall the saw lift up itself without him that uses it, as if one should lift a rod or staff? but it shall not be so;"}}, {"v": 16, "ref": "10:16", "o": "לָ֠/כֵן יְשַׁלַּ֨ח הָ/אָד֜וֹן יְהוָ֧ה צְבָא֛וֹת בְּ/מִשְׁמַנָּ֖י/ו רָז֑וֹן וְ/תַ֧חַת כְּבֹד֛/וֹ יֵקַ֥ד יְקֹ֖ד כִּ/יק֥וֹד אֵֽשׁ", "en": {"kjv": "Therefore shall the Lord, the Lord of hosts, send among his fat ones leanness; and under his glory he shall kindle a burning like the burning of a fire.", "web": "Therefore the Lord, Yahweh of Armies, will send among his fat ones leanness; and under his glory a burning will be kindled like the burning of fire.", "bsb": "Therefore the Lord GOD of Hosts will send a wasting disease among Assyria’s stout warriors, and under his pomp will be kindled a fire like a burning flame.", "asv": "Therefore will the Lord, Jehovah of hosts, send among his fat ones leanness; and under his glory there shall be kindled a burning like the burning of fire.", "ylt": "Therefore doth the Lord, the Lord of Hosts, Send among his fat ones leanness, And under his honour He kindleth a burning As the burning of a fire.", "dra": "Therefore the sovereign Lord, the Lord of hosts, shall send leanness among his fat ones: and under his glory shall be kindled a burning, as it were the burning of a fire.", "bbe": "For this cause the Lord, the Lord of armies, will make his fat become wasted; and in his inner parts a fire will be lighted like a burning flame.", "geneva": "Therefore shall the Lord God of hostes send amog his fat men, leannes, and vnder his glorie he shall kindle a burning, like the burning of fire.", "wycliffe": "For this thing the lordli gouernour, Lord of oostis, schal sende thinnesse in the fatte men of hym, and his glorie kyndlid vndur schal brenne as `the brenning of fier.", "rotherham": "Therefore, shall the Lord, Yahweh of hosts, Send, among his fat ones, leanness, And under his glory, shall he kindle a kindling, like the kindling of fire;", "darby": "Therefore shall the Lord, Jehovah of hosts, send among his fat ones leanness, and under his glory he shall kindle a burning, like the burning of a fire:", "twenty": "", "jps": "Therefore will the L-rd, HaShem of hosts, send among his fat ones leanness; and under his glory there shall be kindled a burning like the burning of fire.", "acv": "Therefore will the Lord, Jehovah of hosts, send among his fat ones, leanness, and under his glory there shall be kindled a burning like the burning of fire.", "anderson": "", "haweis": "", "noyes": "Wherefore the Lord, the Lord of hosts, shall send upon his fat ones leanness, And under his glory shall he kindle a burning, like the burning of a fire.", "webster": "Therefore will the Lord, the LORD of hosts, send among his fat ones leanness; and under his glory he will kindle a burning like the burning of a fire.", "vulgate": "propter hoc mittet Dominator Deus exercituum in pinguibus eius tenuitatem et subtus gloriam eius succensa ardebit quasi conbustio ignis;", "brenton": "but the Lord of hosts shall send dishonour upon thine honour, and burning fire shall be kindled upon thy glory."}}, {"v": 17, "ref": "10:17", "o": "וְ/הָיָ֤ה אֽוֹר יִשְׂרָאֵל֙ לְ/אֵ֔שׁ וּ/קְדוֹשׁ֖/וֹ לְ/לֶהָבָ֑ה וּ/בָעֲרָ֗ה וְ/אָֽכְלָ֛ה שִׁית֥/וֹ וּ/שְׁמִיר֖/וֹ בְּ/י֥וֹם אֶחָֽד", "en": {"kjv": "And the light of Israel shall be for a fire, and his Holy One for a flame: and it shall burn and devour his thorns and his briers in one day;", "web": "The light of Israel will be for a fire, and his Holy One for a flame; and it will burn and devour his thorns and his briers in one day.", "bsb": "And the Light of Israel will become a fire, and its Holy One a flame. In a single day it will burn and devour Assyria’s thorns and thistles.", "asv": "And the light of Israel will be for a fire, and his Holy One for a flame; and it will burn and devour his thorns and his briers in one day.", "ylt": "And the light of Israel hath been for a fire, And his Holy One for a flame, And it hath burned, and devoured his thorn And his brier in one day.", "dra": "And the light of Israel shall be as a fire, and the Holy One thereof as a flame: and his thorns and his briers shall be set on fire, and shall be devoured in one day.", "bbe": "And the light of Israel will be for a fire, and his Holy One for a flame: wasting and burning up his thorns in one day.", "geneva": "And the light of Israel shalbe as a fire, and the Holy one thereof as a flame, and it shall burne, and deuoure his thornes and his briers in one day:", "wycliffe": "And the liyt of Israel schal be in fier, and the hooli of it in flawme; and the thorn of him and brere schal be kyndlid and deuourid in o dai.", "rotherham": "So shall, the Light of Israel, become, a fire, And his Holy One, a flame, Which shall burn and consume his thorns and his briars, in one day;", "darby": "and the light of Israel shall be for a fire, and his Holy One for a flame; and it shall burn and devour his thorns and his briars in one day,", "twenty": "", "jps": "And the light of Israel shall be for a fire, and his Holy One for a flame; and it shall burn and devour his thorns and his briers in one day.", "acv": "And the light of Israel will be for a fire, and his Holy One for a flame, and it will burn and devour his thorns and his briers in one day.", "anderson": "", "haweis": "", "noyes": "The light of Israel shall be a fire, And his Holy One a flame, Which shall burn and devour his thorns and briers in one day.", "webster": "And the light of Israel shall be for a fire, and his Holy One for a flame: and it shall burn and devour his thorns and his briers in one day;", "vulgate": "et erit lumen Israhel in igne et Sanctus eius in flamma et succendetur et devorabitur spina eius et vepres in die una;", "brenton": "And the light of Israel shall be for a fire, and he shall sanctify him with burning fire, and it shall devour the wood as grass."}}, {"v": 18, "ref": "10:18", "o": "וּ/כְב֤וֹד יַעְר/וֹ֙ וְ/כַרְמִלּ֔/וֹ מִ/נֶּ֥פֶשׁ וְ/עַד בָּשָׂ֖ר יְכַלֶּ֑ה וְ/הָיָ֖ה כִּ/מְסֹ֥ס נֹסֵֽס", "en": {"kjv": "And shall consume the glory of his forest, and of his fruitful field, both soul and body: and they shall be as when a standardbearer fainteth.", "web": "He will consume the glory of his forest, and of his fruitful field, both soul and body. It will be as when a standard bearer faints.", "bsb": "The splendor of its forests and orchards, both soul and body, it will completely destroy, as a sickness consumes a man.", "asv": "And he will consume the glory of his forest, and of his fruitful field, both soul and body: and it shall be as when a standard-bearer fainteth.", "ylt": "And the honour of his forest, and his fruitful field, From soul even unto flesh He doth consume, And it hath been as the fainting of a standard-bearer.", "dra": "And the glory of his forest, and of his beautiful hill, shall be consumed from the soul even to the flesh, and he shall run away through fear.", "bbe": "And he will put an end to the glory of his woods and of his planted fields, soul and body together; and it will be as when a man is wasted by disease.", "geneva": "And shall consume the glory of his forest, and of his fruitfull fieldes both soule and flesh: and he shalbe as ye fainting of a standard bearer.", "wycliffe": "And the glorie of his forest and of his Carmele schal be wastid, fro the soule `til to fleisch; and he schal be fleynge awei for drede.", "rotherham": "And the glory of his forest and of his garden land, both soul and body, shall it bring to an end,—And it shall be like the wasting away of a consumptive.", "darby": "and it shall consume the glory of his forest, and of his fruitful field, both soul and body; and they shall be as when a sick man fainteth.", "twenty": "", "jps": "And the glory of his forest and of his fruitful field, he will consume both soul and body; and it shall be as when a sick man wasteth away.", "acv": "And he will consume the glory of his forest, and of his fruitful field, both soul and body. And it shall be as when a standard-bearer faints.", "anderson": "", "haweis": "", "noyes": "The glory of his forest and of his fruitful field From the spirit even to the flesh shall he consume; It shall be with them as when a sick man fainteth.", "webster": "And shall consume the glory of his forest, and of his fruitful field, both soul and body: and they shall be as when a standard-bearer fainteth.", "vulgate": "et gloria saltus eius et Carmeli eius ab anima usque ad carnem consumetur et erit terrore profugus;", "brenton": "In that day the mountains shall be consumed, and the hills, and the forests, and fire shall devour both soul and body: and he that flees shall be as one fleeing from burning flame."}}, {"v": 19, "ref": "10:19", "o": "וּ/שְׁאָ֥ר עֵ֛ץ יַעְר֖/וֹ מִסְפָּ֣ר יִֽהְי֑וּ וְ/נַ֖עַר יִכְתְּבֵֽ/ם", "en": {"kjv": "And the rest of the trees of his forest shall be few, that a child may write them.", "web": "The remnant of the trees of his forest shall be few, so that a child could write their number.", "bsb": "The remaining trees of its forests will be so few that a child could count them.", "asv": "And the remnant of the trees of his forest shall be few, so that a child may write them.", "ylt": "And the rest of the trees of his forest are few, And a youth doth write them.", "dra": "And they that remain of the trees of his forest shall be so few, that they shall easily be numbered, and a child shall write them down.", "bbe": "And the rest of the trees of his wood will be small in number, so that a child may put them down in writing.", "geneva": "And the rest of the trees of his forest shalbe fewe, that a childe may tell them.", "wycliffe": "And the relifs of the tree of his forest schulen be noumbrid for fewnesse, and a child schal write hem.", "rotherham": "And, the remnant of his forest-trees, few in number, shall become,—yea, a child, might describe them!", "darby": "And the remainder of the trees of his forest shall be few: yea, a child might write them.", "twenty": "", "jps": "And the remnant of the trees of his forest shall be few, that a child may write them down.", "acv": "And the remnant of the trees of his forest shall be few, so that a child may write them.", "anderson": "", "haweis": "", "noyes": "The remaining trees of the forest shall be few, So that a child may write them down.", "webster": "And the rest of the trees of his forest shall be few, that a child may write them.", "vulgate": "et reliquiae ligni saltus eius pro paucitate numerabuntur et puer scribet eos;", "brenton": "And they that are left of them shall be a small number, and a child shall write them."}}, {"v": 20, "ref": "10:20", "o": "וְ/הָיָ֣ה בַּ/יּ֣וֹם הַ/ה֗וּא לֹֽא יוֹסִ֨יף ע֜וֹד שְׁאָ֤ר יִשְׂרָאֵל֙ וּ/פְלֵיטַ֣ת בֵּֽית יַעֲקֹ֔ב לְ/הִשָּׁעֵ֖ן עַל מַכֵּ֑/הוּ וְ/נִשְׁעַ֗ן עַל יְהוָ֛ה קְד֥וֹשׁ יִשְׂרָאֵ֖ל בֶּ/אֱמֶֽת", "en": {"kjv": "And it shall come to pass in that day, that the remnant of Israel, and such as are escaped of the house of Jacob, shall no more again stay upon him that smote them; but shall stay upon the Lord, the Holy One of Israel, in truth.", "web": "It will come to pass in that day that the remnant of Israel, and those who have escaped from the house of Jacob will no more again lean on him who struck them, but shall lean on Yahweh, the Holy One of Israel, in truth.", "bsb": "On that day the remnant of Israel and the survivors of the house of Jacob will no longer depend on him who struck them, but they will truly rely on the LORD, the Holy One of Israel.", "asv": "And it shall come to pass in that day, that the remnant of Israel, and they that are escaped of the house of Jacob, shall no more again lean upon him that smote them, but shall lean upon Jehovah, the Holy One of Israel, in truth.", "ylt": "And it hath come to pass, in that day, The remnant of Israel, And the escaped of the house of Jacob, Do not add any more to lean on its smiter, And have leant on Jehovah, The Holy One of Israel, in truth.", "dra": "And it shall come to pass in that day, that the remnant of Israel, and they that shall escape of the house of Jacob, shall lean no more upon him that striketh them: but they shall lean upon the Lord the Holy One of Israel, in truth.", "bbe": "And it will be in that day that the rest of Israel, and those of Jacob who have come safely through these troubles, will no longer go for help to him whose rod was on their back, but their faith will be in the Lord, the Holy One of Israel.", "geneva": "And at that day shall the remnant of Israel, and such as are escaped of the house of Iaakob, stay no more vpon him that smote them, but shall stay vpon ye Lord, ye Holy one of Israel in trueth.", "wycliffe": "And it schal be in that dai, the remenaunt of Israel, and thei that fledden of the house of Jacob, schal not adde for to triste on hym that smytith hem; but it schal triste on the hooli Lord of Israel, in treuthe.", "rotherham": "And it shall come to pass in that day, That the remnant of Israel. And the escaped of the house of Jacob Shall, no more again, lean upon him that smote them,—But shall lean upon Yahweh the Holy One of Israel, in truth.", "darby": "And it shall come to pass in that day, [that] the remnant of Israel and such as are escaped of the house of Jacob shall no more again rely upon him that smote them; but they shall rely upon Jehovah, the Holy One of Israel, in truth.", "twenty": "", "jps": "And it shall come to pass in that day, that the remnant of Israel, and they that are escaped of the house of Jacob, shall no more again stay upon him that smote them; but shall stay upon HaShem, the Holy One of Israel, in truth.", "acv": "And it shall come to pass in that day, that the remnant of Israel, and those who are escaped of the house of Jacob, shall no more again lean upon him who smote them, but shall lean upon Jehovah, the Holy One of Israel, in truth.", "anderson": "", "haweis": "", "noyes": "In that day shall the remnant of Israel, and they that have escaped of the house of Jacob, no more lean upon him that smote them; They shall lean upon Jehovah, the Holy One of Israel, in truth.", "webster": "And it shall come to pass in that day, [that] the remnant of Israel, and such as have escaped of the house of Jacob, shall no more again lean upon him that smote them; but shall lean upon the LORD, the Holy One of Israel, in truth.", "vulgate": "et erit in die illa non adiciet residuum Israhel et hii qui fugerint de domo Iacob inniti super eo qui percutit eos sed innitetur super Dominum Sanctum Israhel in veritate;", "brenton": "And it shall come to pass in that day that the remnant of Israel shall no more join themselves with, and the saved of Jacob shall no more trust in, them that injured them; but they shall trust in the Holy God of Israel, in truth."}}, {"v": 21, "ref": "10:21", "o": "שְׁאָ֥ר יָשׁ֖וּב שְׁאָ֣ר יַעֲקֹ֑ב אֶל אֵ֖ל גִּבּֽוֹר", "en": {"kjv": "The remnant shall return, even the remnant of Jacob, unto the mighty God.", "web": "A remnant will return, even the remnant of Jacob, to the mighty God.", "bsb": "A remnant will return—a remnant of Jacob— to the Mighty God.", "asv": "A remnant shall return, eventhe remnant of Jacob, unto the mighty God.", "ylt": "A remnant returneth--a remnant of Jacob, Unto the Mighty God.", "dra": "The remnant shall be converted, the remnant, I say, of Jacob, to the mighty God.", "bbe": "The rest, even the rest of Jacob, will come back to the Strong God.", "geneva": "The remnant shall returne, euen the remnant of Iaakob vnto the mightie God.", "wycliffe": "The relifs, Y seie, the relifs of Jacob, schulen be conuertid to the stronge Lord.", "rotherham": "A remnant, shall return, The remnant of Jacob,—unto the mighty GOD;", "darby": "The remnant shall return, the remnant of Jacob, unto the mightyGod.", "twenty": "", "jps": "A remnant shall return, even the remnant of Jacob, unto G-d the Mighty.", "acv": "A remnant shall return, even the remnant of Jacob, to the mighty God.", "anderson": "", "haweis": "", "noyes": "The remnant shall return, the remnant of Jacob, to the mighty Potentate;", "webster": "The remnant shall return, [even] the remnant of Jacob, to the mighty God.", "vulgate": "reliquiae convertentur reliquiae inquam Iacob ad Deum fortem;", "brenton": "And the remnant of Jacob shall trust on the mighty God."}}, {"v": 22, "ref": "10:22", "o": "כִּ֣י אִם יִהְיֶ֞ה עַמְּ/ךָ֤ יִשְׂרָאֵל֙ כְּ/ח֣וֹל הַ/יָּ֔ם שְׁאָ֖ר יָשׁ֣וּב בּ֑/וֹ כִּלָּי֥וֹן חָר֖וּץ שׁוֹטֵ֥ף צְדָקָֽה", "en": {"kjv": "For though thy people Israel be as the sand of the sea, yet a remnant of them shall return: the consumption decreed shall overflow with righteousness.", "web": "For though your people, Israel, are like the sand of the sea, only a remnant of them will return. A destruction is determined, overflowing with righteousness.", "bsb": "Though your people, O Israel, be like the sand of the sea, only a remnant will return. Destruction has been decreed, overflowing with righteousness.", "asv": "For though thy people, Israel, be as the sand of the sea, only a remnant of them shall return: a destruction is determined, overflowing with righteousness.", "ylt": "For though thy people Israel be as the sand of the sea, A remnant doth return of it, A consumption determined, Overflowing with righteousness.", "dra": "For if thy people, O Israel, shall be as the sand of the sea, a remnant of them shall be converted, the consumption abridged shall overflow with justice.", "bbe": "For though your people, O Israel, are as the sand of the sea, only a small number will come back: for the destruction is fixed, overflowing in righteousness.", "geneva": "For though thy people, O Israel, be as the sand of the sea, yet shall the remnant of them returne. The consumption decreed shall ouerflow with righteousnesse.", "wycliffe": "Forwhi, Israel, if thi puple is as the grauel of the see, the relifs schulen be turned therof; an endyng maad schort schal make riytfulnesse to be plenteuouse.", "rotherham": "For though thy people, O Israel shall be as the sand of the sea, A [mere] remnant, shall return of them,—A full end decreed, bringeth in, justice, like a flood;", "darby": "For though thy people Israel be as the sand of the sea, [only] a remnant of them shall return: the consumption determined shall overflow in righteousness.", "twenty": "", "jps": "For though thy people, O Israel, be as the sand of the sea, only a remnant of them shall return; an extermination is determined, overflowing with righteousness.", "acv": "For though thy people, Israel, be as the sand of the sea, a remnant of them shall return. A destruction is determined, overflowing with righteousness.", "anderson": "", "haweis": "", "noyes": "For though thy people, O Israel, be as the sand of the sea, Only a remnant of them shall return. The devastation is decreed; It shall overflow with righteousness.", "webster": "For though thy people Israel be as the sand of the sea, [yet] a remnant of them shall return: the consumption decreed shall overflow with righteousness.", "vulgate": "si enim fuerit populus tuus Israhel quasi harena maris reliquiae convertentur ex eo consummatio adbreviata inundabit iustitiam;", "brenton": "And though the people of Israel be as the sand of the sea, a remnant of them shall be saved."}}, {"v": 23, "ref": "10:23", "o": "כִּ֥י כָלָ֖ה וְ/נֶחֱרָצָ֑ה אֲדֹנָ֤/י יְהוִה֙ צְבָא֔וֹת עֹשֶׂ֖ה בְּ/קֶ֥רֶב כָּל הָ/אָֽרֶץ", "en": {"kjv": "For the Lord God of hosts shall make a consumption, even determined, in the midst of all the land.", "web": "For the Lord, Yahweh of Armies, will make a full end, and that determined, in the midst of all the earth.", "bsb": "For the Lord GOD of Hosts will carry out the destruction decreed upon the whole land.", "asv": "For a full end, and that determined, will the Lord, Jehovah of hosts, make in the midst of all the earth.", "ylt": "For a consumption that is determined, The Lord, Jehovah of Hosts, Is making in the midst of all the land.", "dra": "For the Lord God of hosts shall make a consumption, and an abridgment in the midst of all the land.", "bbe": "For the Lord, the Lord of armies, is about to make destruction complete in all the land.", "geneva": "For the Lord God of hostes shall make the consumption, euen determined, in the middes of all the land.", "wycliffe": "For whi the Lord God of oostis schal make an endyng and a breggyng in the myddis of al erthe.", "rotherham": "For, a full end and that a decreed one, is My Lord Yahweh of hosts executing in the midst of all the earth.", "darby": "For a consumption, and [one] determined, will the Lord, Jehovah of hosts, accomplish in the midst of all the land.", "twenty": "", "jps": "For an extermination wholly determined shall the L-rd, the GOD of hosts, make in the midst of all the earth.", "acv": "For a full end, and that determined, the Lord, Jehovah of hosts, will make in the midst of all the earth.", "anderson": "", "haweis": "", "noyes": "For devastation and punishment doth the Lord, Jehovah of hosts, execute in the midst of the whole land,", "webster": "For the Lord GOD of hosts will make a consumption, even determined, in the midst of all the land.", "vulgate": "consummationem enim et adbreviationem Dominus Deus exercituum faciet in medio omnis terrae;", "brenton": "He will finish the work, and cut it short in righteousness: because the Lord will make a short work in all the world."}}, {"v": 24, "ref": "10:24", "o": "לָ/כֵ֗ן כֹּֽה אָמַ֞ר אֲדֹנָ֤/י יְהוִה֙ צְבָא֔וֹת אַל תִּירָ֥א עַמִּ֛/י יֹשֵׁ֥ב צִיּ֖וֹן מֵֽ/אַשּׁ֑וּר בַּ/שֵּׁ֣בֶט יַכֶּ֔/כָּה וּ/מַטֵּ֥/הוּ יִשָּֽׂא עָלֶ֖י/ךָ בְּ/דֶ֥רֶךְ מִצְרָֽיִם", "en": {"kjv": "Therefore thus saith the Lord God of hosts, O my people that dwellest in Zion, be not afraid of the Assyrian: he shall smite thee with a rod, and shall lift up his staff against thee, after the manner of Egypt.", "web": "Therefore the Lord, Yahweh of Armies, says “My people who dwell in Zion, don’t be afraid of the Assyrian, though he strike you with the rod, and lift up his staff against you, as Egypt did.", "bsb": "Therefore this is what the Lord GOD of Hosts says: “O My people who dwell in Zion, do not fear Assyria, who strikes you with a rod and lifts his staff against you as the Egyptians did.", "asv": "Therefore thus saith the Lord, Jehovah of hosts, O my people that dwellest in Zion, be not afraid of the Assyrian, though he smite thee with the rod, and lift up his staff against thee, after the manner of Egypt.", "ylt": "Therefore, thus said the Lord, Jehovah of Hosts, `Be not afraid, my people, inhabiting Zion, because of Asshur, With a rod he doth smite thee, And his staff lifteth up against thee, in the way of Egypt.", "dra": "Therefore, thus saith the Lord the God of hosts: O my people that dwellest in Sion, be not afraid of the Assyrian: he shall strike thee with his rod, and he shall lift up his staff over thee in the way of Egypt.", "bbe": "For this cause the Lord, the Lord of armies, says, O my people living in Zion, have no fear of the Assyrian, even if his rod comes on your back, and his stick is lifted up as in Egypt.", "geneva": "Therefore thus saith ye Lord God of hostes, O my people, that dwellest in Zion, be not afraid of Asshur: he shall smite thee with a rod, and shall lift vp his staffe against thee after the maner of Egypt:", "wycliffe": "For this thing the Lord God of oostis seith these thingis, My puple, the dwellere of Sion, nyle thou drede of Assur, for he schal smite thee in a yerde, and he schal reise his staf on thee in the weie of Egipt.", "rotherham": "Therefore, thus, saith My Lord, Yahweh of hosts, Do not fear O my people dwelling in Zion, because of Assyria,—When with his rod, he would smite thee, And when his staff, he would lift up against thee in the manner of Egypt;", "darby": "Therefore thus saith the Lord, Jehovah of hosts: O my people that dwellest in Zion, be not afraid of the Assyrian; he shall smite thee with a rod, and shall lift up his staff against thee, after the manner of Egypt:", "twenty": "", "jps": "Therefore thus saith the L-rd, the GOD of hosts: O My people that dwellest in Zion, be not afraid of Asshur, though he smite thee with the rod, and lift up his staff against thee, after the manner of Egypt.", "acv": "Therefore thus says the Lord, Jehovah of hosts, O my people who dwell in Zion, be not afraid of the Assyrian, though he smites thee with the rod, and lifts up his staff against thee, according to the manner of Egypt.", "anderson": "", "haweis": "", "noyes": "Yet thus saith the Lord, Jehovah of hosts: Fear not, O my people, that dwellest in Zion, because of the Assyrian! With his rod indeed shall he smite thee, And lift up his staff against thee in the manner of Egypt;", "webster": "Therefore thus saith the Lord GOD of hosts, O my people that dwellest in Zion, be not afraid of the Assyrian: he shall smite thee with a rod, and shall lift up his staff against thee, after the manner of Egypt.", "vulgate": "propter hoc haec dicit Dominus Deus exercituum noli timere populus meus habitator Sion ab Assur in virga percutiet te et baculum suum levabit super te in via Aegypti;", "brenton": "Therefore thus saith the Lord of hosts, Be not afraid, my people who dwell in Sion, of the Assyrians, because he shall smite thee with a rod: for I am bringing a stroke upon thee, that thou mayest see the way of Egypt."}}, {"v": 25, "ref": "10:25", "o": "כִּי ע֖וֹד מְעַ֣ט מִזְעָ֑ר וְ/כָ֣לָה זַ֔עַם וְ/אַפִּ֖/י עַל תַּבְלִיתָֽ/ם", "en": {"kjv": "For yet a very little while, and the indignation shall cease, and mine anger in their destruction.", "web": "For yet a very little while, and the indignation against you will be accomplished, and my anger will be directed to his destruction.”", "bsb": "For in just a little while My fury against you will subside, and My anger will turn to their destruction.”", "asv": "For yet a very little while, and the indignation against thee shall be accomplished, and mine anger shall be directed to his destruction.", "ylt": "For yet a very little, And the indignation hath been completed, And Mine anger by their wearing out.", "dra": "For yet a little and a very little while, and my indignation shall cease, and my wrath shall be upon their wickedness.", "bbe": "For in a very short time my passion will be over, and my wrath will be turned to their destruction.", "geneva": "But yet a very litle time, and the wrath shall be consumed, and mine anger in their destruction.", "wycliffe": "Forwhi yit a litil, and a litil, and myn indignacioun and my strong veniaunce schal be endid on the greet trespas of hem.", "rotherham": "For, yet a very little while, and displeasure shall end, Yea, mine anger, over their destruction.", "darby": "for yet a very little while, and the indignation shall be accomplished, and mine anger, in their destruction.", "twenty": "", "jps": "For yet a very little while, and the indignation shall be accomplished, and Mine anger shall be to their destruction.", "acv": "For yet a very little while, and the indignation shall be accomplished, and my anger is to his destruction.", "anderson": "", "haweis": "", "noyes": "But yet a very little while, and my indignation shall have past, And my anger shall destroy them.", "webster": "For yet a very little while, and the indignation shall cease, and my anger in their destruction.", "vulgate": "adhuc enim paululum modicumque et consummabitur indignatio et furor meus super scelus eorum;", "brenton": "For yet a little while, and the indignation shall cease: but my wrath shall be against their council."}}, {"v": 26, "ref": "10:26", "o": "וְ/עוֹרֵ֨ר עָלָ֜י/ו יְהוָ֤ה צְבָאוֹת֙ שׁ֔וֹט כְּ/מַכַּ֥ת מִדְיָ֖ן בְּ/צ֣וּר עוֹרֵ֑ב וּ/מַטֵּ֨/הוּ֙ עַל הַ/יָּ֔ם וּ/נְשָׂא֖/וֹ בְּ/דֶ֥רֶךְ מִצְרָֽיִם", "en": {"kjv": "And the Lord of hosts shall stir up a scourge for him according to the slaughter of Midian at the rock of Oreb: and as his rod was upon the sea, so shall he lift it up after the manner of Egypt.", "web": "Yahweh of Armies will stir up a scourge against him, as in the slaughter of Midian at the rock of Oreb. His rod will be over the sea, and he will lift it up like he did against Egypt.", "bsb": "And the LORD of Hosts will brandish a whip against them, as when He struck Midian at the rock of Oreb. He will raise His staff over the sea, as He did in Egypt.", "asv": "And Jehovah of hosts will stir up against him a scourge, as in the slaughter of Midian at the rock of Oreb: and his rod will be over the sea, and he will lift it up after the manner of Egypt.", "ylt": "And awaking for him is Jehovah of Hosts, A scourge like the smiting of Midian at the rock Oreb, And his rod is over the sea, And he hath lifted it in the way of Egypt.", "dra": "And the Lord of hosts shall raise up a scourge against him, according to the slaughter of Madian in the rock of Oreb, and his rod over the sea, and he shall lift it up in the way of Egypt.", "bbe": "And the Lord of armies will be shaking a whip against him, as when he overcame Midian at the rock of Oreb: and his rod will be lifted up against them as it was against the Egyptians.", "geneva": "And ye Lord of hostes shall raise vp a scourge for him, according to the plague of Midian in the rocke Oreb: and as his staffe was vpon the Sea, so he will lift it vp after the maner of Egypt.", "wycliffe": "And the Lord of oostis schal reise a scourge on hym bi the veniaunce of Madian in the stoon of Oreb, and bi his yerde on the see; and he schal reise that yerde in the wei of Egipt.", "rotherham": "And Yahweh of hosts, will brandish over him, a scourge—Like the smiting of Midian at the rock Oreb,—And his staff being over the sea, He will lift it up in the manner of Egypt;", "darby": "And Jehovah of hosts will stir up a scourge against him, according to the slaughter of Midian at the rock of Oreb; and his rod [shall be] upon the sea, and he will lift it up after the manner of Egypt.", "twenty": "", "jps": "And HaShem of hosts shall stir up against him a scourge, as in the slaughter of Midian at the Rock of Oreb; and as His rod was over the sea, so shall He lift it up after the manner of Egypt.", "acv": "And Jehovah of hosts will stir up against him a scourge as in the slaughter of Midian at the rock of Oreb. And his rod will be over the sea, and he will lift it up according to the manner of Egypt.", "anderson": "", "haweis": "", "noyes": "Jehovah of hosts shall raise up against him a scourge, As he smote Midian at the rock of Horeb, And as he lifted up the rod against the sea; Yea, he shall lift it up, as in Egypt.", "webster": "And the LORD of hosts will raise up a scourge for him according to the slaughter of Midian at the rock of Oreb: and [as] his rod [was] upon the sea, so shall he lift it up after the manner of Egypt.", "vulgate": "et suscitabit super eum Dominus exercituum flagellum iuxta plagam Madian in petra Oreb et virgam suam super mare et levabit eam in via Aegypti;", "brenton": "And God will stir up enemies against them, according to the stroke of Madiam in the place of affliction: and his wrath shall be by the way of the sea, even to the way that leads to Egypt."}}, {"v": 27, "ref": "10:27", "o": "וְ/הָיָ֣ה בַּ/יּ֣וֹם הַ/ה֗וּא יָס֤וּר סֻבֳּל/וֹ֙ מֵ/עַ֣ל שִׁכְמֶ֔/ךָ וְ/עֻלּ֖/וֹ מֵ/עַ֣ל צַוָּארֶ֑/ךָ וְ/חֻבַּ֥ל עֹ֖ל מִ/פְּנֵי שָֽׁמֶן", "en": {"kjv": "And it shall come to pass in that day, that his burden shall be taken away from off thy shoulder, and his yoke from off thy neck, and the yoke shall be destroyed because of the anointing.", "web": "It will happen in that day, that his burden will depart from off your shoulder, and his yoke from off your neck, and the yoke shall be destroyed because of the anointing oil.", "bsb": "On that day the burden will be lifted from your shoulders, and the yoke from your neck. The yoke will be broken because your neck will be too large.", "asv": "And it shall come to pass in that day, that his burden shall depart from off thy shoulder, and his yoke from off thy neck, and the yoke shall be destroyed by reason of fatness.", "ylt": "And it hath come to pass, in that day, Turned is his burden from off thy shoulder, And his yoke from off thy neck, And destroyed hath been the yoke, because of prosperity.", "dra": "And it shall come to pass in that day, that his burden shall be taken away from off thy shoulder, and his yoke from off thy neck, and the yoke shall putrefy at the presence of the oil.", "bbe": "And in that day the weight which he put on your back will be taken away, and his yoke broken from off your neck.", "geneva": "And at that day shall his burden be taken away from off thy shoulder, and his yoke from off thy necke: and the yoke shalbe destroied because of the anoynting.", "wycliffe": "And it schal be in that dai, his birthun schal be takun awei fro thi schuldre, and his yok fro thi necke; and the yok schal wexe rotun fro the face of oile.", "rotherham": "And it shall come to pass, in that day, That his burden shall remove from off thy shoulder, And his yoke from off thy neck,—Yea, the yoke shall be broken because of fatness.", "darby": "And it shall come to pass in that day, [that] his burden shall be taken away from off thy shoulder, and his yoke from off thy neck; and the yoke shall be destroyed because of the anointing. ...", "twenty": "", "jps": "And it shall come to pass in that day, that his burden shall depart from off thy shoulder, and his yoke from off thy neck, and the yoke shall be destroyed by reason of fatness.", "acv": "And it shall come to pass in that day, that his burden shall depart from off thy shoulder, and his yoke from off thy neck, and the yoke shall be destroyed because of fatness.", "anderson": "", "haweis": "", "noyes": "In that day shall his burden be removed from thy shoulder, And his yoke from thy neck; Yea, thy yoke shall be broken, as that of a fat steer.", "webster": "And it shall come to pass in that day, [that] his burden shall be taken away from off thy shoulder, and his yoke from off thy neck, and the yoke shall be destroyed because of the anointing.", "vulgate": "et erit in die illa auferetur onus eius de umero tuo et iugum eius de collo tuo et conputrescet iugum a facie olei;", "brenton": "And it shall come to pass in that day, that his yoke shall be taken away from thy shoulder, and his fear from thee, and the yoke shall be destroyed from off your shoulders."}}, {"v": 28, "ref": "10:28", "o": "בָּ֥א עַל עַיַּ֖ת עָבַ֣ר בְּ/מִגְר֑וֹן לְ/מִכְמָ֖שׂ יַפְקִ֥יד כֵּלָֽי/ו", "en": {"kjv": "He is come to Aiath, he is passed to Migron; at Michmash he hath laid up his carriages:", "web": "He has come to Aiath. He has passed through Migron. At Michmash he stores his baggage.", "bsb": "Assyria has entered Aiath and passed through Migron, storing their supplies at Michmash.", "asv": "He is come to Aiath, he is passed through Migron; at Michmash he layeth up his baggage;", "ylt": "He hath come in against Aiath, He hath passed over into Migron, At Michmash he looketh after his vessels.", "dra": "He shall come into Aiath, he shall pass into Magron: at Machmas he shall lay up his carriages.", "bbe": "He has gone up from Pene-Rimmon, he has come to Aiath; he has gone past Migron, at Michmash he puts his forces in order.", "geneva": "He is come to Aiath: he is passed into Migron: at Michmash shall he lay vp his armour.", "wycliffe": "He schal come in to Aioth, he schal passe in to Magron, at Magynas he schal bitake his vessels to kepyng.", "rotherham": "He hath come in unto Ayyath, Hath passed through Migron,—At Michmash, storeth his baggage:", "darby": "He is come to Aiath, he hath passed through Migron; at Michmash he layeth up his baggage.", "twenty": "", "jps": "He is come to Aiath, he is passed through Migron; at Michmas he layeth up his baggage;", "acv": "He has come to Aiath. He has passed through Migron. At Michmash he lays up his baggage.", "anderson": "", "haweis": "", "noyes": "He is come to Aiath; he passeth through Migron; In Michmash he leaveth his baggage;", "webster": "He is come to Aiath, he is passed to Migron; at Michmash he hath laid up his furniture.", "vulgate": "veniet in Aiath transibit in Magron apud Machmas commendabit vasa sua;", "brenton": "For he shall arrive at the city of Angai, and shall pass on to Maggedo, and shall lay up his stores in Machmas."}}, {"v": 29, "ref": "10:29", "o": "עָֽבְרוּ֙ מַעְבָּרָ֔ה גֶּ֖בַע מָל֣וֹן לָ֑/נוּ חָֽרְדָה֙ הָֽ/רָמָ֔ה גִּבְעַ֥ת שָׁא֖וּל נָֽסָה", "en": {"kjv": "They are gone over the passage: they have taken up their lodging at Geba; Ramah is afraid; Gibeah of Saul is fled.", "web": "They have gone over the pass. They have taken up their lodging at Geba. Ramah trembles. Gibeah of Saul has fled.", "bsb": "They have crossed at the ford: “We will spend the night at Geba.” Ramah trembles; Gibeah of Saul flees.", "asv": "they are gone over the pass; they have taken up their lodging at Geba; Ramah trembleth; Gibeah of Saul is fled.", "ylt": "They have gone over the passage, Geba they have made a lodging place, Trembled hath Rama, Gibeah of Saul fled.", "dra": "They have passed in haste, Gaba is our lodging: Rama was astonished, Gabaath of Saul fled away.", "bbe": "They have gone across the mountain; Geba will be our resting-place tonight, they say: Ramah is shaking with fear; Gibeah of Saul has gone in flight.", "geneva": "They haue gone ouer the foorde: they lodged in the lodging at Geba: Ramah is afraide: Gibeah of Saul is fled away.", "wycliffe": "Thei passiden swiftli, Gabaa is oure seete, Rama was astonyed, Gabaa of Saul fled.", "rotherham": "They have passed over the pass, Geba is his halting-place,—Terror-stricken is Ramah, Gibeah of Saul, hath fled!", "darby": "They are gone through the pass; they make their lodging at Geba: Ramah trembleth, Gibeah of Saul is fled.", "twenty": "", "jps": "They are gone over the pass; they have taken up their lodging at Geba; Ramah trembleth; Gibeath-shaul is fled.", "acv": "They have gone over the pass. They have taken up their lodging at Geba. Ramah trembles. Gibeah of Saul has fled.", "anderson": "", "haweis": "", "noyes": "They pass the strait; At Geba they make their night-quarters; Ramah trembleth; Gibeah of Saul fleeth.", "webster": "They have gone over the passage: they have taken up their lodging at Geba; Ramah is afraid; Gibeah of Saul hath fled.", "vulgate": "transierunt cursim Gabee sedes nostra obstipuit Rama Gabaath Saulis fugit;", "brenton": "And he shall pass by the valley, and shall arrive at Angai: fear shall seize upon Rama, the city of Saul."}}, {"v": 30, "ref": "10:30", "o": "צַהֲלִ֥י קוֹלֵ֖/ךְ בַּת גַּלִּ֑ים הַקְשִׁ֥יבִי לַ֖יְשָׁה עֲנִיָּ֥ה עֲנָתֽוֹת", "en": {"kjv": "Lift up thy voice, O daughter of Gallim: cause it to be heard unto Laish, O poor Anathoth.", "web": "Cry aloud with your voice, daughter of Gallim! Listen, Laishah! You poor Anathoth!", "bsb": "Cry aloud, O Daughter of Gallim! Listen, O Laishah! O wretched Anathoth!", "asv": "Cry aloud with thy voice, O daughter of Gallim! hearken, O Laishah! O thou poor Anathoth!", "ylt": "Cry aloud with thy voice, daughter of Gallim, Give attention, Laish! answer her, Anathoth.", "dra": "Lift up thy voice, O daughter of Gallim, attend, O Laisa, poor Anathoth.", "bbe": "Give a loud cry, daughter of Gallim; let Laishah give ear; let Anathoth give answer to her.", "geneva": "Lift vp thy voyce, O daughter Gallim, cause Laish to heare, O poore Anathoth.", "wycliffe": "Thou douytir of Gallym, weile with thi vois; thou Laisa, perseyue, thou pore Anatot.", "rotherham": "Make shrill thy voice, O daughter of Gallim! Hearken, O Laishah, Answer, O Anathoth!", "darby": "Lift up thy voice, daughter of Gallim! Hearken, O Laish! — Poor Anathoth!", "twenty": "", "jps": "Cry thou with a shrill voice, O daughter of Gallim! Hearken, O Laish! O thou poor Anathoth!", "acv": "Cry aloud with thy voice, O daughter of Gallim! Hearken, O Laishah! O thou poor Anathoth!", "anderson": "", "haweis": "", "noyes": "Cry aloud, O daughter of Gallim! Hear, O Laish! Alas, poor Anathoth!", "webster": "Lift up thy voice, O daughter of Gallim: cause it to be heard to Laish, O poor Anathoth.", "vulgate": "hinni voce tua filia Gallim adtende Laisa paupercula Anathoth;", "brenton": "The daughter of Gallim shall flee; Laisa shall hear; one shall hear in Anathoth."}}, {"v": 31, "ref": "10:31", "o": "נָדְדָ֖ה מַדְמֵנָ֑ה יֹשְׁבֵ֥י הַ/גֵּבִ֖ים הֵעִֽיזוּ", "en": {"kjv": "Madmenah is removed; the inhabitants of Gebim gather themselves to flee.", "web": "Madmenah is a fugitive. The inhabitants of Gebim flee for safety.", "bsb": "Madmenah flees; the people of Gebim take refuge.", "asv": "Madmenah is a fugitive; the inhabitants of Gebim flee for safety.", "ylt": "Fled away hath Madmenah, The inhabitants of the high places have hardened themselves.", "dra": "Medemena is removed: ye inhabitants of Gabim, take courage.", "bbe": "Madmenah has gone; the men of Gebim are putting their goods in a safe place.", "geneva": "Madmenah is remoued: the inhabitants of Gebim haue gathered themselues together.", "wycliffe": "Medemena passide; the dwelleris of Gabyn fledden; be ye coumfortid.", "rotherham": "Madmenah, hath fled,—The inhabitants of Gebim, have gone into safety:", "darby": "Madmenah is fugitive; the inhabitants of Gebim take to flight.", "twenty": "", "jps": "Madmenah is in mad flight; the inhabitants of Gebim flee to cover.", "acv": "Madmenah is a fugitive. The inhabitants of Gebim flee for safety.", "anderson": "", "haweis": "", "noyes": "Madmenah hasteth away; The inhabitants of Gebim take to flight.", "webster": "Madmenah is removed; the inhabitants of Gebim gather themselves to flee.", "vulgate": "migravit Medemena habitatores Gebim confortamini;", "brenton": "Madebena also is amazed, and the inhabitants of Gibbir."}}, {"v": 32, "ref": "10:32", "o": "ע֥וֹד הַ/יּ֖וֹם בְּ/נֹ֣ב לַֽ/עֲמֹ֑ד יְנֹפֵ֤ף יָד/וֹ֙ הַ֣ר בית בַּת צִיּ֔וֹן גִּבְעַ֖ת יְרוּשָׁלִָֽם", "en": {"kjv": "As yet shall he remain at Nob that day: he shall shake his hand against the mount of the daughter of Zion, the hill of Jerusalem.", "web": "This very day he will halt at Nob. He shakes his hand at the mountain of the daughter of Zion, the hill of Jerusalem.", "bsb": "Yet today they will halt at Nob, shaking a fist at the mount of Daughter Zion, at the hill of Jerusalem.", "asv": "This very day shall he halt at Nob: he shaketh his hand at the mount of the daughter of Zion, the hill of Jerusalem.", "ylt": "Yet to-day in Nob to remain, Wave its hand doth the mount of the daughter of Zion, The hill of Jerusalem.", "dra": "It is yet day enough, to remain in Nobe: he shall shake his hand against the mountain of the daughter of Sion, the hill of Jerusalem.", "bbe": "This very day he is stopping at Nob; he is shaking his hand against the mountain of the daughter of Zion, the hill of Jerusalem.", "geneva": "Yet there is a time that he will stay at Nob: he shall lift vp his hand towarde the mount of the daughter Zion, the hill of Ierusalem.", "wycliffe": "Yit it is dai, that me stonde in Nobe; he schal dryue his hond on the hil of the douyter of Syon, on the litil hil of Jerusalem.", "rotherham": "While yet to-day, in Nob, he tarrieth, He brandisheth his hand toward The mount of the daughter of Zion, The hill of Jerusalem.", "darby": "Still a day of halting at Nob; he shaketh his hand [against] the mount of the daughter of Zion, the hill of Jerusalem. ...", "twenty": "", "jps": "This very day shall he halt at Nob, shaking his hand at the mount of the daughter of Zion, the hill of Jerusalem.", "acv": "This very day he shall halt at Nob. He shakes his hand at the mount of the daughter of Zion, the hill of Jerusalem.", "anderson": "", "haweis": "", "noyes": "Yet one day shall he rest at Nob, Then shall he shake his hand against the mount of the daughter of Zion, The hill of Jerusalem.", "webster": "As yet shall he remain at Nob that day: he shall shake his hand [against] the mount of the daughter of Zion, the hill of Jerusalem.", "vulgate": "adhuc dies est ut in Nob stetur agitabit manum suam super montem filiae Sion collem Hierusalem;", "brenton": "Exhort ye them to-day to remain in the way: exhort ye beckoning with the hand the mountain, the daughter of Sion, even ye hills that are in Jerusalem."}}, {"v": 33, "ref": "10:33", "o": "הִנֵּ֤ה הָ/אָדוֹן֙ יְהוָ֣ה צְבָא֔וֹת מְסָעֵ֥ף פֻּארָ֖ה בְּ/מַעֲרָצָ֑ה וְ/רָמֵ֤י הַ/קּוֹמָה֙ גְּדוּעִ֔ים וְ/הַ/גְּבֹהִ֖ים יִשְׁפָּֽלוּ", "en": {"kjv": "Behold, the Lord, the Lord of hosts, shall lop the bough with terror: and the high ones of stature shall be hewn down, and the haughty shall be humbled.", "web": "Behold, the Lord, Yahweh of Armies, will lop the boughs with terror. The tall will be cut down, and the lofty will be brought low.", "bsb": "Behold, the Lord GOD of Hosts will lop off the branches with terrifying power. The tall trees will be cut down, the lofty ones will be felled.", "asv": "Behold, the Lord, Jehovah of hosts, will lop the boughs with terror: and the high of stature shall be hewn down, and the lofty shall be brought low.", "ylt": "Lo, the Lord, Jehovah of Hosts, Is lopping a branch with violence, And the high of stature are cut down, And the lofty are become low,", "dra": "Behold the sovereign Lord of hosts shall break the earthen vessel with terror, and the tall of stature shall be cut down, and the lofty shall be humbled.", "bbe": "See, the Lord, the Lord of armies, is cutting off his branches with a great noise, and his strong ones are falling and his high ones are coming down.", "geneva": "Beholde, the Lord God of hostes shall cut off the bough with feare, and they of high stature shalbe cut off, and the hie shalbe humbled.", "wycliffe": "Lo! the lordli gouernour, the Lord of oostis, schal breke a potel in drede, and hiy men of stature schulen be kit doun.", "rotherham": "Behold! the Lord, Yahweh of hosts, is about to lop off a tree-crown, with a crash,—Then shall, they who are lifted on high, be hewn down, And, the lofty, be laid low;", "darby": "Behold the Lord, Jehovah of hosts, shall lop the boughs with violence; and the high ones of stature shall be hewn down, and the haughty shall be brought low;", "twenty": "", "jps": "Behold, the L-rd, HaShem of hosts, shall lop the boughs with terror; and the high ones of stature shall be hewn down, and the lofty shall be laid low.", "acv": "Behold, the Lord, Jehovah of hosts, will lop off the boughs with terror. And the high of stature shall be hewn down, and the lofty shall be brought low.", "anderson": "", "haweis": "", "noyes": "But behold! the Lord, Jehovah of hosts, shall lop the branches with fearful force, And the high of stature shall be cut down, And the lofty shall be brought low.", "webster": "Behold, the Lord, the LORD of hosts will lop the bough with terror: and the high ones of stature [shall be] hewn down, and the haughty shall be humbled.", "vulgate": "ecce Dominator Dominus exercituum confringet lagunculam in terrore et excelsi statura succidentur et sublimes humiliabuntur;", "brenton": "Behold, the Lord, the Lord of hosts, will mightily confound the glorious ones; and the haughty in pride shall be crushed, and the lofty shall be brought low:"}}, {"v": 34, "ref": "10:34", "o": "וְ/נִקַּ֛ף סִֽבְכֵ֥י הַ/יַּ֖עַר בַּ/בַּרְזֶ֑ל וְ/הַ/לְּבָנ֖וֹן בְּ/אַדִּ֥יר יִפּֽוֹל", "en": {"kjv": "And he shall cut down the thickets of the forest with iron, and Lebanon shall fall by a mighty one.", "web": "He will cut down the thickets of the forest with iron, and Lebanon will fall by the Mighty One.", "bsb": "He will clear the forest thickets with an axe, and Lebanon will fall before the Mighty One.", "asv": "And he will cut down the thickets of the forest with iron, and Lebanon shall fall by a mighty one.", "ylt": "And He hath gone round the thickets of the forest with iron, And Lebanon by a mighty one falleth!", "dra": "And the thickets of the forest shall be cut down with iron, and Libanus with its high ones shall fall.", "bbe": "And he is cutting down the thick places of the wood with an axe, and Lebanon with its tall trees is coming down.", "geneva": "And he shall cut away the thicke places of the forest with yron, and Lebanon shall haue a mightie fall.", "wycliffe": "And proude men schulen be maade low, and the thicke thingis of the forest schulen be distried bi irun; and the Liban with hiy thingis schal falle doun.", "rotherham": "Then will he fell the thickets of the forest with iron,—And, Lebanon by a majestic one shall fall.", "darby": "and he shall make clearings in the thickets of the forest with iron; and Lebanon shall fall by a mighty one.", "twenty": "", "jps": "And He shall cut down the thickets of the forest with iron, and Lebanon shall fall by a mighty one.", "acv": "And he will cut down the thickets of the forest with iron, and Lebanon shall fall by a mighty one.", "anderson": "", "haweis": "", "noyes": "He shall hew the thickets of the forest with iron, And Lebanon shall fall by a mighty hand.", "webster": "And he shall cut down the thickets of the forests with iron, and Lebanon shall fall by a mighty one.", "vulgate": "et subvertentur condensa saltus ferro et Libanus cum excelsis cadet;", "brenton": "and the lofty ones shall fall by the sword, and the Libanus shall fall with his lofty ones."}}]}, {"c": 11, "verses": [{"v": 1, "ref": "11:1", "o": "וְ/יָצָ֥א חֹ֖טֶר מִ/גֵּ֣זַע יִשָׁ֑י וְ/נֵ֖צֶר מִ/שָּׁרָשָׁ֥י/ו יִפְרֶֽה", "en": {"kjv": "And there shall come forth a rod out of the stem of Jesse, and a Branch shall grow out of his roots:", "web": "A shoot will come out of the stock of Jesse, and a branch out of his roots will bear fruit.", "bsb": "Then a shoot will spring up from the stump of Jesse, and a Branch from his roots will bear fruit.", "asv": "And there shall come forth a shoot out of the stock of Jesse, and a branch out of his roots shall bear fruit.", "ylt": "And a rod hath come out from the stock of Jesse, And a branch from his roots is fruitful.", "dra": "And there shall come forth a rod out of the root of Jesse, and a flower shall rise up out of his root.", "bbe": "And there will come a rod out of the broken tree of Jesse, and a branch out of his roots will give fruit.", "geneva": "But there shall come a rodde foorth of the stocke of Ishai, and a grasse shall growe out of his rootes.", "wycliffe": "And a yerde schal go out of the roote of Jesse, and a flour schal stie of the roote of it.", "rotherham": "But there shall come forth a shoot from the stock of Jesse,—And, a sprout from his roots, shall bear fruit;", "darby": "And there shall come forth a shoot out of the stock of Jesse, and a branch out of his roots shall be fruitful;", "twenty": "", "jps": "And there shall come forth a shoot out of the stock of Jesse, and a twig shall grow forth out of his roots.", "acv": "And there shall come forth a shoot out of the stock of Jesse. And a branch out of his roots shall bear fruit.", "anderson": "", "haweis": "", "noyes": "Then shall spring forth a shoot from the stem of Jesse, And a sprout grow up from his roots.", "webster": "And there shall come forth a rod out of the stem of Jesse, and a branch shall grow out of his roots:", "vulgate": "et egredietur virga de radice Iesse et flos de radice eius ascendet;", "brenton": "And there shall come forth a rod out of the root of Jesse, and a blossom shall come up from his root:"}}, {"v": 2, "ref": "11:2", "o": "וְ/נָחָ֥ה עָלָ֖י/ו ר֣וּחַ יְהוָ֑ה ר֧וּחַ חָכְמָ֣ה וּ/בִינָ֗ה ר֤וּחַ עֵצָה֙ וּ/גְבוּרָ֔ה ר֥וּחַ דַּ֖עַת וְ/יִרְאַ֥ת יְהוָֽה", "en": {"kjv": "And the spirit of the Lord shall rest upon him, the spirit of wisdom and understanding, the spirit of counsel and might, the spirit of knowledge and of the fear of the Lord;", "web": "The Spirit of Yahweh will rest on him: the spirit of wisdom and understanding, the spirit of counsel and might, the spirit of knowledge and of the fear of Yahweh.", "bsb": "The Spirit of the LORD will rest on Him— the Spirit of wisdom and understanding, the Spirit of counsel and strength, the Spirit of knowledge and fear of the LORD.", "asv": "And the Spirit of Jehovah shall rest upon him, the spirit of wisdom and understanding, the spirit of counsel and might, the spirit of knowledge and of the fear of Jehovah.", "ylt": "Rested on him hath the Spirit of Jehovah, The spirit of wisdom and understanding, The spirit of counsel and might, The spirit of knowledge and fear of Jehovah.", "dra": "And the spirit of the Lord shall rest upon him: the spirit of wisdom, and of understanding, the spirit of counsel, and of fortitude, the spirit of knowledge, and of godliness.", "bbe": "And the spirit of the Lord will be resting on him, the spirit of wisdom and good sense, the spirit of wise guiding and strength, the spirit of knowledge and of the fear of the Lord;", "geneva": "And the Spirite of the Lord shall rest vpon him: the Spirite of wisedome and vnderstanding, the Spirite of counsell and strength, the Spirite of knowledge, and of the feare of the Lord,", "wycliffe": "And the Spirit of the Lord schal reste on hym, the spirit of wisdom and of vndurstondyng, the spirit of counsel and of strengthe, the spirit of kunnyng and of pitee;", "rotherham": "And the spirit of Yahweh shall rest upon him,—The spirit of wisdom and understanding, The spirit of counsel and might, The spirit of knowledge and reverence of Yahweh;", "darby": "and the Spirit of Jehovah shall rest upon him, the spirit of wisdom and understanding, the spirit of counsel and might, the spirit of knowledge and of the fear of Jehovah.", "twenty": "", "jps": "And the spirit of HaShem shall rest upon him, the spirit of wisdom and understanding, the spirit of counsel and might, the spirit of knowledge and of the fear of HaShem.", "acv": "And the Spirit of Jehovah shall rest upon him, the spirit of wisdom and understanding, the spirit of counsel and might, the spirit of knowledge and of the fear of Jehovah.", "anderson": "", "haweis": "", "noyes": "The spirit of Jehovah shall rest upon him, The spirit of wisdom and understanding, The spirit of counsel and might, The spirit of the knowledge and of the fear of Jehovah,", "webster": "And the spirit of the LORD will rest upon him, the spirit of wisdom and understanding, the spirit of counsel and might, the spirit of knowledge and of the fear of the LORD;", "vulgate": "et requiescet super eum spiritus Domini spiritus sapientiae et intellectus spiritus consilii et fortitudinis spiritus scientiae et pietatis;", "brenton": "and the Spirit of God shall rest upon him, the spirit of wisdom and understanding, the spirit of counsel and strength, the spirit of knowledge and godliness shall fill him;"}}, {"v": 3, "ref": "11:3", "o": "וַ/הֲרִיח֖/וֹ בְּ/יִרְאַ֣ת יְהוָ֑ה וְ/לֹֽא לְ/מַרְאֵ֤ה עֵינָי/ו֙ יִשְׁפּ֔וֹט וְ/לֹֽא לְ/מִשְׁמַ֥ע אָזְנָ֖י/ו יוֹכִֽיחַ", "en": {"kjv": "And shall make him of quick understanding in the fear of the Lord: and he shall not judge after the sight of his eyes, neither reprove after the hearing of his ears:", "web": "His delight will be in the fear of Yahweh. He will not judge by the sight of his eyes, neither decide by the hearing of his ears;", "bsb": "And He will delight in the fear of the LORD. He will not judge by what His eyes see, and He will not decide by what His ears hear,", "asv": "And his delight shall be in the fear of Jehovah; and he shall not judge after the sight of his eyes, neither decide after the hearing of his ears;", "ylt": "To refresh him in the fear of Jehovah, And by the sight of his eyes he judgeth not, Nor by the hearing of his ears decideth.", "dra": "And he shall be filled with the spirit of the fear of the Lord, He shall not judge according to the sight of the eyes, nor reprove according to the hearing of the ears.", "bbe": "And he will not be guided in his judging by what he sees, or give decisions by the hearing of his ears:", "geneva": "And shall make him prudent in the feare of the Lord: for he shall not iudge after the sight of his eies, neither reproue by ye hearing of his eares.", "wycliffe": "and the spirit of the drede of the Lord schal fille him. He schal deme not bi the siyt of iyen, nether he schal repreue bi the heryng of eeris;", "rotherham": "So will he find fragrance, in the reverence of Yahweh, And not, by the sight of his eyes, will he judge, Nor by the hearing of his ears, will he decide;", "darby": "And his delight will be in the fear of Jehovah; and he shall not judge after the sight of his eyes, neither reprove after the hearing of his ears;", "twenty": "", "jps": "And his delight shall be in the fear of HaShem; and he shall not judge after the sight of his eyes, neither decide after the hearing of his ears;", "acv": "And his delight shall be in the fear of Jehovah. And he shall not judge according to the sight of his eyes, nor decide according to the hearing of his ears,", "anderson": "", "haweis": "", "noyes": "He shall take delight in the fear of Jehovah; He shall not judge by the sight of his eyes, Nor decide by the hearing of his ears.", "webster": "And will make him of quick understanding in the fear of the LORD: and he will not judge after the sight of his eyes, neither reprove after the hearing of his ears:", "vulgate": "et replebit eum spiritus timoris Domini non secundum visionem oculorum iudicabit neque secundum auditum aurium arguet;", "brenton": "the spirit of the fear of God. He shall not judge according to appearance, nor reprove according to report:"}}, {"v": 4, "ref": "11:4", "o": "וְ/שָׁפַ֤ט בְּ/צֶ֨דֶק֙ דַּלִּ֔ים וְ/הוֹכִ֥יחַ בְּ/מִישׁ֖וֹר לְ/עַנְוֵי אָ֑רֶץ וְ/הִֽכָּה אֶ֨רֶץ֙ בְּ/שֵׁ֣בֶט פִּ֔י/ו וּ/בְ/ר֥וּחַ שְׂפָתָ֖י/ו יָמִ֥ית רָשָֽׁע", "en": {"kjv": "But with righteousness shall he judge the poor, and reprove with equity for the meek of the earth: and he shall smite the earth with the rod of his mouth, and with the breath of his lips shall he slay the wicked.", "web": "but with righteousness he will judge the poor, and decide with equity for the humble of the earth. He will strike the earth with the rod of his mouth; and with the breath of his lips he will kill the wicked.", "bsb": "but with righteousness He will judge the poor, and with equity He will decide for the lowly of the earth. He will strike the earth with the rod of His mouth and slay the wicked with the breath of His lips.", "asv": "but with righteousness shall he judge the poor, and decide with equity for the meek of the earth; and he shall smite the earth with the rod of his mouth; and with the breath of his lips shall he slay the wicked.", "ylt": "And he hath judged in righteousness the poor, And decided in uprightness for the humble of earth, And hath smitten earth with the rod of his mouth, And with the breath of his lips he putteth the wicked to death.", "dra": "But he shall judge the poor with justice, and shall reprove with equity the meek of the earth: and he shall strike the earth with the rod of his mouth, and with the breath of his lips he shall slay the wicked.", "bbe": "But he will do right in the cause of the poor, and give wise decisions for those in the land who are in need; and the rod of his mouth will come down on the cruel, and with the breath of his lips he will put an end to the evil-doer.", "geneva": "But with righteousnesse shall he iudge the poore, and with equitie shall he reprooue for the meeke of the earth: and he shall smite the earth with the rod of his mouth, and with the breath of his lippes shall he slay the wicked.", "wycliffe": "but he schal deme in riytfulnesse pore men, and he schal repreue in equyte, for the mylde men of erthe. And he schal smyte the lond with the yerde of his mouth, and bi the spirit of his lippis he schal sle the wickid man.", "rotherham": "But he will judge with righteousness! them who are poor, And decide with equity! for the oppressed of the land,—And he will smite the land With the sceptre of his mouth, And with the breath of his lips, will he slay the lawless one;", "darby": "but with righteousness shall he judge the poor, and reprove with equity the meek of the earth: and he shall smite the earth with the rod of his mouth, and with the breath of his lips shall he slay the wicked.", "twenty": "", "jps": "But with righteousness shall he judge the poor, and decide with equity for the meek of the land; and he shall smite the land with the rod of his mouth, and with the breath of his lips shall he slay the wicked.", "acv": "but with righteousness he shall judge the poor, and decide with equity for the meek of the earth. And he shall smite the earth with the rod of his mouth, and with the breath of his lips he shall kill the wicked.", "anderson": "", "haweis": "", "noyes": "But with righteousness shall he judge the poor, And decide with equity for the afflicted of the land; He shall smite the earth with the rod of his mouth; With the breath of his lips shall he slay the wicked.", "webster": "But with righteousness will he judge the poor, and reprove with equity for the meek of the earth: and he will smite the earth with the rod of his mouth, and with the breath of his lips will he slay the wicked.", "vulgate": "sed iudicabit in iustitia pauperes et arguet in aequitate pro mansuetis terrae et percutiet terram virga oris sui et spiritu labiorum suorum interficiet impium;", "brenton": "but he shall judge the cause of the lowly, and shall reprove the lowly of the earth: and he shall smite the earth with the word of his mouth, and with the breath of his lips shall he destroy the ungodly one."}}, {"v": 5, "ref": "11:5", "o": "וְ/הָ֥יָה צֶ֖דֶק אֵז֣וֹר מָתְנָ֑י/ו וְ/הָ/אֱמוּנָ֖ה אֵז֥וֹר חֲלָצָֽי/ו", "en": {"kjv": "And righteousness shall be the girdle of his loins, and faithfulness the girdle of his reins.", "web": "Righteousness will be the belt of his waist, and faithfulness the belt of his waist.", "bsb": "Righteousness will be the belt around His hips, and faithfulness the sash around His waist.", "asv": "And righteousness shall be the girdle of his waist, and faithfulness the girdle of his loins.", "ylt": "And righteousness hath been the girdle of his loins, And faithfulness--the girdle of his reins.", "dra": "And justice shall be the girdle of his loins: and faith the girdle of his reins.", "bbe": "And righteousness will be the cord of his robe, and good faith the band round his breast.", "geneva": "And iustice shall be ye girdle of his loynes, and faithfulnesse the girdle of his reines.", "wycliffe": "And riytfulnesse schal be the girdil of hise leendis, and feith schal be the girdyng of hise reynes.", "rotherham": "And righteousness shall be the girdle of his loins,—And faithfulness the girdle of his reins;", "darby": "And righteousness shall be the girdle of his reins, and faithfulness the girdle of his loins.", "twenty": "", "jps": "And righteousness shall be the girdle of his loins, and faithfulness the girdle of his reins.", "acv": "And righteousness shall be the belt of his waist, and faithfulness the belt of his loins.", "anderson": "", "haweis": "", "noyes": "Righteousness shall be the girdle of his loins, And faithfulness the girdle of his reins.", "webster": "And righteousness shall be the girdle of his loins, and faithfulness the girdle of his reins.", "vulgate": "et erit iustitia cingulum lumborum eius et fides cinctorium renis eius;", "brenton": "And he shall have his loins girt with righteousness, and his sides clothed with truth."}}, {"v": 6, "ref": "11:6", "o": "וְ/גָ֤ר זְאֵב֙ עִם כֶּ֔בֶשׂ וְ/נָמֵ֖ר עִם גְּדִ֣י יִרְבָּ֑ץ וְ/עֵ֨גֶל וּ/כְפִ֤יר וּ/מְרִיא֙ יַחְדָּ֔ו וְ/נַ֥עַר קָטֹ֖ן נֹהֵ֥ג בָּֽ/ם", "en": {"kjv": "The wolf also shall dwell with the lamb, and the leopard shall lie down with the kid; and the calf and the young lion and the fatling together; and a little child shall lead them.", "web": "The wolf will live with the lamb, and the leopard will lie down with the young goat; The calf, the young lion, and the fattened calf together; and a little child will lead them.", "bsb": "The wolf will live with the lamb, and the leopard will lie down with the goat; the calf and young lion and fatling will be together, and a little child will lead them.", "asv": "And the wolf shall dwell with the lamb, and the leopard shall lie down with the kid; and the calf and the young lion and the fatling together; and a little child shall lead them.", "ylt": "And a wolf hath sojourned with a lamb, And a leopard with a kid doth lie down, And calf, and young lion, and fatling are together, And a little youth is leader over them.", "dra": "The wolf shall dwell with the lamb: and the leopard shall lie down with the kid: the calf and the lion, and the sheep shall abide together, and a little child shall lead them.", "bbe": "And the wolf will be living with the lamb, and the leopard will take his rest with the young goat; and the lion will take grass for food like the ox; and the young lion will go with the young ones of the herd; and a little child will be their guide.", "geneva": "The wolfe also shall dwell with the lambe, and the leopard shall lie with the kid, and the calfe, and the lyon, and the fat beast together, and a litle childe shall leade them.", "wycliffe": "A wolf schal dwelle with a lombe, and a parde schal reste with a kide; a calf, and a lioun, and a scheep schulen dwelle togidere, and a litil child schal dryue hem.", "rotherham": "And the wolf shall dwell with the lamb, And, the leopard, with the kid, shall lie down,—And the calf and the young lion and the fatling—together, With, a little child, leading them;", "darby": "The wolf also shall dwell with the lamb, and the leopard shall lie down with the kid, and the calf and the young lion and the fatted beast together, and a little child shall lead them.", "twenty": "", "jps": "And the wolf shall dwell with the lamb, and the leopard shall lie down with the kid; and the calf and the young lion and the fatling together; and a little child shall lead them.", "acv": "And the wolf shall dwell with the lamb, and the leopard shall lie down with the kid, and the calf and the young lion and the fatling together, and a little child shall lead them.", "anderson": "", "haweis": "", "noyes": "Then shall the wolf dwell with the lamb, And the leopard shall lie down with the kid; The calf, and the young lion, and the fatling shall be together, And a little child shall lead them.", "webster": "The wolf also shall dwell with the lamb, and the leopard shall lie down with the kid; and the calf and the young lion and the fatling together; and a little child shall lead them.", "vulgate": "habitabit lupus cum agno et pardus cum hedo accubabit vitulus et leo et ovis simul morabuntur et puer parvulus minabit eos;", "brenton": "And the wolf shall feed with the lamb, and the leopard shall lie down with the kid; and the young calf and bull and lion shall feed together; and a little child shall lead them."}}, {"v": 7, "ref": "11:7", "o": "וּ/פָרָ֤ה וָ/דֹב֙ תִּרְעֶ֔ינָה יַחְדָּ֖ו יִרְבְּצ֣וּ יַלְדֵי/הֶ֑ן וְ/אַרְיֵ֖ה כַּ/בָּקָ֥ר יֹֽאכַל תֶּֽבֶן", "en": {"kjv": "And the cow and the bear shall feed; their young ones shall lie down together: and the lion shall eat straw like the ox.", "web": "The cow and the bear will graze. Their young ones will lie down together. The lion will eat straw like the ox.", "bsb": "The cow will graze with the bear, their young will lie down together, and the lion will eat straw like the ox.", "asv": "And the cow and the bear shall feed; their young ones shall lie down together; and the lion shall eat straw like the ox.", "ylt": "And cow and bear do feed, Together lie down their young ones, And a lion as an ox eateth straw.", "dra": "The calf and the bear shall feed: their young ones shall rest together: and the lion shall eat straw like the ox.", "bbe": "And the cow and the bear will be friends while their young ones are sleeping together.", "geneva": "And the kow and the beare shall feede: their yong ones shall lie together: and the lyon shall eate strawe like the bullocke.", "wycliffe": "A calf and a beere schulen be lesewid togidere; the whelpis of hem schulen reste, and a lioun as an oxe schal ete stre.", "rotherham": "And the cow, with the bear shall find pasture, Together, shall their young ones, lie down,—And, the lion, like the ox, shall eat straw;", "darby": "And the cow and the she-bear shall feed; their young ones shall lie down together; and the lion shall eat straw like the ox.", "twenty": "", "jps": "And the cow and the bear feed; their young ones shall lie down together; and the lion shall eat straw like the ox.", "acv": "And the cow and the bear shall feed; their young ones shall lie down together. And the lion shall eat straw like the ox.", "anderson": "", "haweis": "", "noyes": "The cow and the bear shall feed together, Together shall their young lie down, And the lion shall eat straw like the ox.", "webster": "And the cow and the bear shall feed; their young ones shall lie down together: and the lion shall eat straw like the ox.", "vulgate": "vitulus et ursus pascentur simul requiescent catuli eorum et leo quasi bos comedet paleas;", "brenton": "And the ox and bear shall feed together; and their young shall be together: and the lion shall eat straw like the ox."}}, {"v": 8, "ref": "11:8", "o": "וְ/שִֽׁעֲשַׁ֥ע יוֹנֵ֖ק עַל חֻ֣ר פָּ֑תֶן וְ/עַל֙ מְאוּרַ֣ת צִפְעוֹנִ֔י גָּמ֖וּל יָד֥/וֹ הָדָֽה", "en": {"kjv": "And the sucking child shall play on the hole of the asp, and the weaned child shall put his hand on the cockatrice’ den.", "web": "The nursing child will play near a cobra’s hole, and the weaned child will put his hand on the viper’s den.", "bsb": "The infant will play by the cobra’s den, and the toddler will reach into the viper’s nest.", "asv": "And the sucking child shall play on the hole of the asp, and the weaned child shall put his hand on the adder’s den.", "ylt": "And played hath a suckling by the hole of an asp, And on the den of a cockatrice Hath the weaned one put his hand.", "dra": "And the sucking child shall play on other hole of the asp: and the weaned child shall thrust his hand into the den of the basilisk.", "bbe": "And the child at the breast will be playing by the hole of the snake, and the older child will put his hand on the bright eye of the poison-snake.", "geneva": "And the sucking childe shall play vpon the hole of the aspe, and the wained childe shall put his hand vpon the cockatrice hole.", "wycliffe": "And a yonge soukyng child fro the tete schal delite on the hole of a snake, and he that is wenyd schal putte his hond in the caue of a cocatrice.", "rotherham": "And the sucking child shall caress over the hole of the asp, Yea over the viper’s den, hath the weaned child stretched out his hand:", "darby": "And the sucking child shall play on the hole of the adder, and the weaned child shall put forth its hand to the viper's den.", "twenty": "", "jps": "And the sucking child shall play on the hole of the asp, and the weaned child shall put his hand on the basilisk's den.", "acv": "And the sucking child shall play on the hole of the asp, and the weaned child shall put his hand on the adder's den.", "anderson": "", "haweis": "", "noyes": "The suckling shall play upon the hole of the asp, And the near-weaned child lay his hand on the hiding-place of the basilisk.", "webster": "And the suckling child shall play on the hole of the asp, and the weaned child shall put his hand on the den of the basilisk.", "vulgate": "et delectabitur infans ab ubere super foramine aspidis et in caverna reguli qui ablactatus fuerit manum suam mittet;", "brenton": "And an infant shall put his hand on the holes of asps, and on the nest of young asps."}}, {"v": 9, "ref": "11:9", "o": "לֹֽא יָרֵ֥עוּ וְ/לֹֽא יַשְׁחִ֖יתוּ בְּ/כָל הַ֣ר קָדְשִׁ֑/י כִּֽי מָלְאָ֣ה הָ/אָ֗רֶץ דֵּעָה֙ אֶת יְהוָ֔ה כַּ/מַּ֖יִם לַ/יָּ֥ם מְכַסִּֽים", "en": {"kjv": "They shall not hurt nor destroy in all my holy mountain: for the earth shall be full of the knowledge of the Lord, as the waters cover the sea.", "web": "They will not hurt nor destroy in all my holy mountain; for the earth will be full of the knowledge of Yahweh, as the waters cover the sea.", "bsb": "They will neither harm nor destroy on all My holy mountain, for the earth will be full of the knowledge of the LORD as the sea is full of water.", "asv": "They shall not hurt nor destroy in all my holy mountain; for the earth shall be full of the knowledge of Jehovah, as the waters cover the sea.", "ylt": "Evil they do not, nor destroy in all My holy mountain, For full hath been the earth with the knowledge of Jehovah, As the waters are covering the sea.", "dra": "They shall not hurt, nor shall they kill in all my holy mountain, for the earth is filled with the knowledge of the Lord, as the covering waters of the sea.", "bbe": "There will be no cause of pain or destruction in all my holy mountain: for the earth will be full of the knowledge of the Lord as the sea is covered by the waters.", "geneva": "Then shall none hurt nor destroy in all the mountaine of mine holines: for the earth shalbe full of the knowledge of the Lord, as the waters that couer the sea.", "wycliffe": "Thei schulen not anoye, and schulen not sle in al myn hooli hil; forwhi the erthe is fillid with the kunnyng of the Lord, as watris of the see hilynge.", "rotherham": "They shall not hurt—nor destroy, in all my holy mountain,—For filled is the land with the knowledge of Yahweh, As the waters, to the sea, form a covering.", "darby": "They shall not hurt nor destroy in all my holy mountain; for the earth shall be full of the knowledge of Jehovah, as the waters cover the sea.", "twenty": "", "jps": "They shall not hurt nor destroy in all My holy mountain; for the earth shall be full of the knowledge of HaShem, as the waters cover the sea.", "acv": "They shall not hurt nor destroy in all my holy mountain, for the earth shall be full of the knowledge of Jehovah as the waters cover the sea.", "anderson": "", "haweis": "", "noyes": "They shall not hurt nor destroy in all my holy mountain; For the land shall be full of the knowledge of Jehovah, As the waters cover the depths of the sea.", "webster": "They shall not hurt nor destroy in all my holy mountain: for the earth shall be full of the knowledge of the LORD, as the waters cover the sea.", "vulgate": "non nocebunt et non occident in universo monte sancto meo quia repleta est terra scientia Domini sicut aquae maris operientes;", "brenton": "And they shall not hurt, nor shall they at all be able to destroy any one on my holy mountain: for the whole world is filled with the knowledge of the Lord, as much water covers the seas."}}, {"v": 10, "ref": "11:10", "o": "וְ/הָיָה֙ בַּ/יּ֣וֹם הַ/ה֔וּא שֹׁ֣רֶשׁ יִשַׁ֗י אֲשֶׁ֤ר עֹמֵד֙ לְ/נֵ֣ס עַמִּ֔ים אֵלָ֖י/ו גּוֹיִ֣ם יִדְרֹ֑שׁוּ וְ/הָיְתָ֥ה מְנֻחָת֖/וֹ כָּבֽוֹד", "en": {"kjv": "And in that day there shall be a root of Jesse, which shall stand for an ensign of the people; to it shall the Gentiles seek: and his rest shall be glorious.", "web": "It will happen in that day that the nations will seek the root of Jesse, who stands as a banner of the peoples; and his resting place will be glorious.", "bsb": "On that day the Root of Jesse will stand as a banner for the peoples. The nations will seek Him, and His place of rest will be glorious.", "asv": "And it shall come to pass in that day, that the root of Jesse, that standeth for an ensign of the peoples, unto him shall the nations seek; and his resting-place shall be glorious.", "ylt": "And there hath been, in that day, A root of Jesse that is standing for an ensign of peoples, Unto him do nations seek, And his rest hath been--honour!", "dra": "In that day the root of Jesse, who standeth for an ensign of the people, him the Gentiles shall beseech, and his sepulchre shall be glorious.", "bbe": "And in that day, the eyes of the nations will be turned to the root of Jesse which will be lifted up as the flag of the peoples; and his resting-place will be glory.", "geneva": "And in that day the roote of Ishai, which shall stand vp for a signe vnto the people, the nations shall seeke vnto it, and his rest shall be glorious.", "wycliffe": "In that dai the roote of Jesse, that stondith in to the signe of puplis; hethene men schulen biseche hym, and his sepulchre schal be gloriouse.", "rotherham": "And there shall come to be, in that day, A root of Jesse, which shall be standing as an ensign of peoples, Unto him, shall nations seek,—And, his resting-place, shall be, glorious.", "darby": "And in that day there shall be a root of Jesse, standing as a banner of the peoples: the nations shall seek it; and his resting-place shall be glory.", "twenty": "", "jps": "And it shall come to pass in that day, that the root of Jesse, that standeth for an ensign of the peoples, unto him shall the nations seek; and his resting-place shall be glorious.", "acv": "And in that day there shall be a root of Jesse, and he who arises to rule over the Gentiles. In him shall the Gentiles hope, and his resting-place shall be glorious.", "anderson": "", "haweis": "", "noyes": "In that day shall the shoot of Jesse stand as a banner to the nations, And to him shall the gentiles repair, And his dwelling-place shall be glorious.", "webster": "And in that day there shall be a root of Jesse, which shall stand for an ensign of the people; to it shall the Gentiles seek: and his rest shall be glorious.", "vulgate": "in die illa radix Iesse qui stat in signum populorum ipsum gentes deprecabuntur et erit sepulchrum eius gloriosum;", "brenton": "And in that day there shall be a root of Jesse, and he that shall arise to rule over the Gentiles; in him shall the Gentiles trust, and his rest shall be glorious."}}, {"v": 11, "ref": "11:11", "o": "וְ/הָיָ֣ה בַּ/יּ֣וֹם הַ/ה֗וּא יוֹסִ֨יף אֲדֹנָ֤/י שֵׁנִית֙ יָד֔/וֹ לִ/קְנ֖וֹת אֶת שְׁאָ֣ר עַמּ֑/וֹ אֲשֶׁ֣ר יִשָּׁאֵר֩ מֵ/אַשּׁ֨וּר וּ/מִ/מִּצְרַ֜יִם וּ/מִ/פַּתְר֣וֹס וּ/מִ/כּ֗וּשׁ וּ/מֵ/עֵילָ֤ם וּ/מִ/שִּׁנְעָר֙ וּ/מֵ֣/חֲמָ֔ת וּ/מֵ/אִיֵּ֖י הַ/יָּֽם", "en": {"kjv": "And it shall come to pass in that day, that the Lord shall set his hand again the second time to recover the remnant of his people, which shall be left, from Assyria, and from Egypt, and from Pathros, and from Cush, and from Elam, and from Shinar, and from Hamath, and from the islands of the sea.", "web": "It will happen in that day that the Lord will set his hand again the second time to recover the remnant that is left of his people from Assyria, from Egypt, from Pathros, from Cush, from Elam, from Shinar, from Hamath, and from the islands of the sea.", "bsb": "On that day the Lord will extend His hand a second time to recover the remnant of His people from Assyria, from Egypt, from Pathros, from Cush, from Elam, from Shinar, from Hamath, and from the islands of the sea.", "asv": "And it shall come to pass in that day, that the Lord will set his hand again the second time to recover the remnant of his people, that shall remain, from Assyria, and from Egypt, and from Pathros, and from Cush, and from Elam, and from Shinar, and from Hamath, and from the islands of the sea.", "ylt": "And it hath come to pass, in that day, The Lord addeth a second time his power, To get the remnant of His people that is left, From Asshur, and from Egypt, And from Pathros, and from Cush, And from Elam, and from Shinar, And from Hamath, and from isles of the sea,", "dra": "And it shall come to pass in that day, that the Lord shall set his hand the second time to possess the remnant of his people, which shall be left from the Assyrians, and from Egypt, and from Phetros, and from Ethiopia, and from Elam, and from Sennaar, and from Emath, and from the islands of the sea.", "bbe": "And in that day the hand of the Lord will be stretched out the second time to get back the rest of his people, from Assyria, and from Egypt, and from Pathros, and from Cush, and from Elam, and from Shinar, and from Hamath, and from the sea-lands.", "geneva": "And in the same day shall the Lord stretche out his hand againe the second time, to possesse the remnant of his people, (which shalbe left) of Asshur, and of Egypt, and of Pathros, and of Ethiopia, and of Elam, and of Shinear, and of Hamath, and of the yles of the sea.", "wycliffe": "And it schal be in that day, the Lord schal adde the secounde tyme his hond to haue in possessioun the residue of his puple that schal be left, of Assiriens, and of Egipt, and of Fethros, and of Ethiope, and of Elan, and of Sennar, and of Emath, and of ylis of the see.", "rotherham": "And it shall come to pass in that day, That My Lord will again a second time set his hand, to possess himself of the remnant of his people,—who shall be left—from Assyria and from Egypt and from Pathros and from Ethiopia and from Elam and from Shinar and from Hamath and from the Coastlands of the sea;", "darby": "And it shall come to pass in that day, [that] the Lord shall set his hand again the second time to acquire the remnant of his people which shall be left, from Assyria, and from Egypt, and from Pathros, and from Cush, and from Elam, and from Shinar, and from Hamath, and from the islands of the sea.", "twenty": "", "jps": "And it shall come to pass in that day, that the L-rd will set His hand again the second time to recover the remnant of His people, that shall remain from Assyria, and from Egypt, and from Pathros, and from Cush, and from Elam, and from Shinar, and from Hamath, and from the islands of the sea.", "acv": "And it shall come to pass in that day, that the Lord will set his hand again the second time to recover the remnant of his people, who shall remain, from Assyria, and from Egypt, and from Pathros, and from Cush, and from Elam, and from Shinar, and from Hamath, and from the islands of the sea.", "anderson": "", "haweis": "", "noyes": "In that day shall Jehovah the second time stretch forth his hand To recover the remnant of his people, That remaineth, from Assyria, and from Egypt, And from Pathros, and from Ethiopia, and from Elam, And from Shinar, and from Hamath, And from the islands of the sea.", "webster": "And it shall come to pass in that day, [that] the Lord will set his hand again the second time to recover the remnant of his people, which shall be left, from Assyria, and from Egypt, and from Pathros, and from Cush, and from Elam, and from Shinar, and from Hamath, and from the isles of the sea.", "vulgate": "et erit in die illa adiciet Dominus secundo manum suam ad possidendum residuum populi sui quod relinquetur ab Assyriis et ab Aegypto et a Fetros et ab Aethiopia et ab Aelam et a Sennaar et ab Emath et ab insulis maris;", "brenton": "And it shall be in that day, that the Lord shall again shew his hand, to be zealous for the remnant that is left of the people, which shall be left by the Assyrians, and that from Egypt, and from the country of Babylon, and from Ethiopia, and from the Elamites, and from the rising of the sun, and out of Arabia."}}, {"v": 12, "ref": "11:12", "o": "וְ/נָשָׂ֥א נֵס֙ לַ/גּוֹיִ֔ם וְ/אָסַ֖ף נִדְחֵ֣י יִשְׂרָאֵ֑ל וּ/נְפֻצ֤וֹת יְהוּדָה֙ יְקַבֵּ֔ץ מֵ/אַרְבַּ֖ע כַּנְפ֥וֹת הָ/אָֽרֶץ", "en": {"kjv": "And he shall set up an ensign for the nations, and shall assemble the outcasts of Israel, and gather together the dispersed of Judah from the four corners of the earth.", "web": "He will set up a banner for the nations, and will assemble the outcasts of Israel, and gather together the dispersed of Judah from the four corners of the earth.", "bsb": "He will raise a banner for the nations and gather the exiles of Israel; He will collect the scattered of Judah from the four corners of the earth.", "asv": "And he will set up an ensign for the nations, and will assemble the outcasts of Israel, and gather together the dispersed of Judah from the four corners of the earth.", "ylt": "And He hath lifted up an ensign to nations, And gathereth the driven away of Israel, And the scattered of Judah He assembleth, From the four wings of the earth.", "dra": "And he shall set up a standard unto the nations, and shall assemble the fugitives of Israel, and shall gather together the dispersed of Juda from the four quarters of the earth.", "bbe": "And he will put up a flag as a sign to the nations, and he will get together those of Israel who had been sent away, and the wandering ones of Judah, from the four ends of the earth.", "geneva": "And he shall set vp a signe to the nations, and assemble the dispersed of Israel, and gather the scattered of Iudah from the foure corners of the worlde.", "wycliffe": "And he schal reise a sygne to naciouns, and schal gadere togidere the fleeris awei of Israel; and he schal gadere togidere the scaterid men of Juda fro foure coostis of erthe.", "rotherham": "And he will lift up a standard to the nations, And will gather the outcasts of Israel,—And the dispersed of Judah, will he collect, From the four corners of the earth.", "darby": "And he shall lift up a banner to the nations, and shall assemble the outcasts of Israel, and gather together the dispersed of Judah from the four corners of the earth.", "twenty": "", "jps": "And He will set up an ensign for the nations, and will assemble the dispersed of Israel, and gather together the scattered of Judah from the four corners of the earth.", "acv": "And he will set up an ensign for the nations, and will assemble the outcasts of Israel, and gather together the dispersed of Judah from the four corners of the earth.", "anderson": "", "haweis": "", "noyes": "He shall set up a banner to the nations, And gather the outcasts of Israel, And bring together the dispersed of Judah, From the four extremities of the earth.", "webster": "And he shall set up an ensign for the nations, and shall assemble the outcasts of Israel, and gather the dispersed of Judah from the four corners of the earth.", "vulgate": "et levabit signum in nationes et congregabit profugos Israhel et dispersos Iuda colliget a quattuor plagis terrae;", "brenton": "And he shall lift up a standard for the nations, and he shall gather the lost ones of Israel, and he shall gather the dispersed of Juda from the four corners of the earth."}}, {"v": 13, "ref": "11:13", "o": "וְ/סָ֨רָה֙ קִנְאַ֣ת אֶפְרַ֔יִם וְ/צֹרְרֵ֥י יְהוּדָ֖ה יִכָּרֵ֑תוּ אֶפְרַ֨יִם֙ לֹֽא יְקַנֵּ֣א אֶת יְהוּדָ֔ה וִֽ/יהוּדָ֖ה לֹֽא יָצֹ֥ר אֶת אֶפְרָֽיִם", "en": {"kjv": "The envy also of Ephraim shall depart, and the adversaries of Judah shall be cut off: Ephraim shall not envy Judah, and Judah shall not vex Ephraim.", "web": "The envy also of Ephraim will depart, and those who persecute Judah will be cut off. Ephraim won’t envy Judah, and Judah won’t persecute Ephraim.", "bsb": "Then the jealousy of Ephraim will depart, and the adversaries of Judah will be cut off. Ephraim will no longer envy Judah, nor will Judah harass Ephraim.", "asv": "The envy also of Ephraim shall depart, and they that vex Judah shall be cut off: Ephraim shall not envy Judah, and Judah shall not vex Ephraim.", "ylt": "And turned aside hath the envy of Ephraim, And the adversaries of Judah are cut off, Ephraim doth not envy Judah, And Judah doth not distress Ephraim.", "dra": "And the envy of Ephraim shall be taken away, and the enemies of Juda shall perish: Ephraim shall not envy Juda, and Juda shall not fight against Ephraim.", "bbe": "And the envy of Ephraim will be gone, and those who make trouble for Judah will come to an end: Ephraim will have no more envy of Judah, and there will be an end of Judah's hate for Ephraim.", "geneva": "The hatred also of Ephraim shall depart, and the aduersaries of Iudah shalbe cut off: Ephraim shall not enuie Iudah, neither shall Iudah vexe Ephraim:", "wycliffe": "And the enuye of Effraym schal be don awei, and the enemyes of Juda schulen perische; Effraym schal not haue enuye to Juda, and Juda schal not fiyte ayens Effraym.", "rotherham": "And the envy of Ephraim shall be removed, And the vexatious doings of Judah, shall be cut off: Ephraim shall not envy Judah, and Judah, shall not vex Ephraim;", "darby": "And the envy of Ephraim shall depart, and the troublers of Judah shall be cut off; Ephraim will not envy Judah, and Judah will not trouble Ephraim:", "twenty": "", "jps": "The envy also of Ephraim shall depart, and they that harass Judah shall be cut off; Ephraim shall not envy Judah, and Judah shall not vex Ephraim.", "acv": "Also the envy of Ephraim shall depart, and those who vex Judah shall be cut off. Ephraim shall not envy Judah, and Judah shall not vex Ephraim.", "anderson": "", "haweis": "", "noyes": "Then shall the jealousy of Ephraim depart, And the enmity in Judah be at an end; Ephraim shall not be jealous of Judah, And Judah shall not contend with Ephraim.", "webster": "The envy also of Ephraim shall depart, and the adversaries of Judah shall be cut off: Ephraim shall not envy Judah, and Judah shall not distress Ephraim.", "vulgate": "et auferetur zelus Ephraim et hostes Iuda peribunt Ephraim non aemulabitur Iudam et Iudas non pugnabit contra Ephraim;", "brenton": "And the envy of Ephraim shall be taken away, and the enemies of Juda shall perish: Ephraim shall not envy Juda, and Juda shall not afflict Ephraim."}}, {"v": 14, "ref": "11:14", "o": "וְ/עָפ֨וּ בְ/כָתֵ֤ף פְּלִשְׁתִּים֙ יָ֔מָּ/ה יַחְדָּ֖ו יָבֹ֣זּוּ אֶת בְּנֵי קֶ֑דֶם אֱד֤וֹם וּ/מוֹאָב֙ מִשְׁל֣וֹח יָדָ֔/ם וּ/בְנֵ֥י עַמּ֖וֹן מִשְׁמַעְתָּֽ/ם", "en": {"kjv": "But they shall fly upon the shoulders of the Philistines toward the west; they shall spoil them of the east together: they shall lay their hand upon Edom and Moab; and the children of Ammon shall obey them.", "web": "They will fly down on the shoulders of the Philistines on the west. Together they will plunder the children of the east. They will extend their power over Edom and Moab, and the children of Ammon will obey them.", "bsb": "They will swoop down on the slopes of the Philistines to the west; together they will plunder the sons of the east. They will lay their hands on Edom and Moab, and the Ammonites will be subject to them.", "asv": "And they shall fly down upon the shoulder of the Philistines on the west; together shall they despoil the children of the east: they shall put forth their hand upon Edom and Moab; and the children of Ammon shall obey them.", "ylt": "And they have flown on the shoulder of the Philistines westward, Together they spoil the sons of the east, Edom and Moab sending forth their hand, And sons of Ammon obeying them.", "dra": "But they shall fly upon the shoulders of the Philistines by the sea, they together shall spoil the children of the east: Edom, till Moab shall be under the rule of their hand, and the children of Ammon shall be obedient.", "bbe": "And they will be united in attacking the Philistines on the west, and together they will take the goods of the children of the east: their hand will be on Edom and Moab; and the children of Ammon will be under their rule.", "geneva": "But they shall flee vpon the shoulders of the Philistims toward the West: they shall spoyle them of the East together: Edom and Moab shall be the stretching out of their hands, and the children of Ammon in their obedience.", "wycliffe": "And thei schulen flie in to the schuldris of Filisteis bi the see, thei schulen take prey togidere of the sones of the eest; Ydume and Moab schulen be the comaundement of the hond of hem, and the sones of Amon schulen be obedient.", "rotherham": "But they shall fly on the wing of the Philistines in the west, Together, shall they make prey of the sons of the east,—On Edom and Moab, putting forth their hand, With the sons of Ammon hearkening unto them.", "darby": "but they shall fly upon the shoulder of the Philistines towards the west; together shall they spoil the sons of the east; they shall lay their hand upon Edom and Moab, and the children of Ammon shall obey them.", "twenty": "", "jps": "And they shall fly down upon the shoulder of the Philistines on the west; together shall they spoil the children of the east; they shall put forth their hand upon Edom and Moab; and the children of Ammon shall obey them.", "acv": "And they shall fly down upon the shoulder of the Philistines on the west. Together they shall despoil the sons of the east. They shall put forth their hand upon Edom and Moab, and the sons of Ammon shall obey them.", "anderson": "", "haweis": "", "noyes": "But they shall fly upon the shoulders of the Philistines at the sea; Together shall they plunder the children of the East; On Edom and Moab shall they lay their hand, And the sons of Ammon shall be subject to them.", "webster": "But they shall fly upon the shoulders of the Philistines towards the west; they shall spoil them of the east together: they shall lay their hand upon Edom and Moab; and the children of Ammon shall obey them.", "vulgate": "et volabunt in umeros Philisthim per mare simul praedabuntur filios orientis Idumea et Moab praeceptum manus eorum et filii Ammon oboedientes erunt;", "brenton": "And they shall fly in the ships of the Philistines: they shall at the same time spoil the sea, and them that come from the east, and Idumea: and they shall lay their hands on Moab first; but the children of Ammon shall first obey them."}}, {"v": 15, "ref": "11:15", "o": "וְ/הֶחֱרִ֣ים יְהוָ֗ה אֵ֚ת לְשׁ֣וֹן יָם מִצְרַ֔יִם וְ/הֵנִ֥יף יָד֛/וֹ עַל הַ/נָּהָ֖ר בַּ/עְיָ֣ם רוּח֑/וֹ וְ/הִכָּ֨/הוּ֙ לְ/שִׁבְעָ֣ה נְחָלִ֔ים וְ/הִדְרִ֖יךְ בַּ/נְּעָלִֽים", "en": {"kjv": "And the Lord shall utterly destroy the tongue of the Egyptian sea; and with his mighty wind shall he shake his hand over the river, and shall smite it in the seven streams, and make men go over dryshod.", "web": "Yahweh will utterly destroy the tongue of the Egyptian sea; and with his scorching wind he will wave his hand over the River, and will split it into seven streams, and cause men to march over in sandals.", "bsb": "The LORD will devote to destruction the gulf of the Sea of Egypt; with a scorching wind He will sweep His hand over the Euphrates. He will split it into seven streams for men to cross with dry sandals.", "asv": "And Jehovah will utterly destroy the tongue of the Egyptian sea; and with his scorching wind will he wave his hand over the River, and will smite it into seven streams, and cause men to march over dryshod.", "ylt": "And Jehovah hath devoted to destruction The tongue of the sea of Egypt, And hath waved His hand over the river, In the terror of his wind, And hath smitten it at the seven streams, And hath caused men to tread it with shoes.", "dra": "And the Lord shall lay waste the tongue of the sea of Egypt, and shall lift up his hand over the river in the strength of his spirit: and he shall strike it in the seven streams, so that men may pass through it in their shoes.", "bbe": "And the Lord will make the tongue of the Egyptian sea completely dry; and with his burning wind his hand will be stretched out over the River, and it will be parted into seven streams, so that men may go over it with dry feet.", "geneva": "The Lord also shall vtterly destroy the tongue of the Egyptians sea, and with his mightie winde shall lift vp his hand ouer the riuer, and shall smite him in his seuen streames, and cause men to walke therein with shooes.", "wycliffe": "And the Lord schal make desolat the tunge of the see of Egipt, and he schal reise his hond on the flood in the strengthe of his spirit; and he schal smyte, ethir departe, it in seuene ryueris, so that schood men passe bi it.", "rotherham": "And Yahweh, will devote to destruction, the gulf of the Egyptian sea, And will brandish his hand against the River [=\"Euphrates\"], in the full force of his spirit,—And will smite it in the seven streams And cause a marching through in sandals,", "darby": "And Jehovah will utterly destroy the tongue of the Egyptian sea; and with his mighty wind will he shake his hand over the river, and will smite it into seven streams, and make [men] go over dryshod.", "twenty": "", "jps": "And HaShem will utterly destroy the tongue of the Egyptian sea; and with His scorching wind will He shake His hand over the River, and will smite it into seven streams, and cause men to march over dry-shod.", "acv": "And Jehovah will utterly destroy the tongue of the Egyptian sea. And with his scorching wind he will wave his hand over the River, and will smite it into seven streams, and cause men to march over dry shod.", "anderson": "", "haweis": "", "noyes": "Then will Jehovah utterly destroy the tongue of the Egyptian sea, And shake his hand over the river with a mighty wind, And smite it into seven streams, So that men may go over it dry-shod.", "webster": "And the LORD will utterly destroy the tongue of the Egyptian sea; and with his mighty wind will he shake his hand over the river, and will smite it in the seven streams, and make [men] go over dry shod.", "vulgate": "et desolabit Dominus linguam maris Aegypti et levabit manum suam super Flumen in fortitudine spiritus sui et percutiet eum in septem rivis ita ut transeant per eum calciati;", "brenton": "And the Lord shall make desolate the sea of Egypt; and he shall lay his hand on the river with a strong wind, and he shall smite the seven channels, so that men shall pass through it dry-shod."}}, {"v": 16, "ref": "11:16", "o": "וְ/הָיְתָ֣ה מְסִלָּ֔ה לִ/שְׁאָ֣ר עַמּ֔/וֹ אֲשֶׁ֥ר יִשָּׁאֵ֖ר מֵֽ/אַשּׁ֑וּר כַּ/אֲשֶׁ֤ר הָֽיְתָה֙ לְ/יִשְׂרָאֵ֔ל בְּ/י֥וֹם עֲלֹת֖/וֹ מֵ/אֶ֥רֶץ מִצְרָֽיִם", "en": {"kjv": "And there shall be an highway for the remnant of his people, which shall be left, from Assyria; like as it was to Israel in the day that he came up out of the land of Egypt.", "web": "There will be a highway for the remnant that is left of his people from Assyria, like there was for Israel in the day that he came up out of the land of Egypt.", "bsb": "There will be a highway for the remnant of His people who remain from Assyria, as there was for Israel when they came up from the land of Egypt.", "asv": "And there shall be a highway for the remnant of his people, that shall remain, from Assyria; like as there was for Israel in the day that he came up out of the land of Egypt.", "ylt": "And there hath been a highway, For the remnant of His people that is left, from Asshur, As there was for Israel in the day of his coming up out of the land of Egypt!", "dra": "And there shall be a highway for the remnant of my people, which shall be left from the Assyrians: as there was for Israel in the day that he came up out of the land of Egypt.", "bbe": "And there will be a highway for the rest of his people from Assyria; as there was for Israel in the day when he came up out of the land of Egypt.", "geneva": "And there shalbe a path to the remnant of his people, which are left of Asshur, like as it was vnto Israel in the day that he came vp out of the land of Egypt.", "wycliffe": "And a weie schal be to my residue puple that schal be left, of Assiriens, as it was to Israel, in the dai in which it stiede fro the lond of Egipt.", "rotherham": "So shall there be a highway for the remnant of his people who shall be left out of Assyria,—Like as it was to Israel, in the day that he came up out of the land of Egypt!", "darby": "And there shall be a highway for the remnant of his people which will be left, from Assyria; like as it was to Israel in the day when he went up out of the land of Egypt.", "twenty": "", "jps": "And there shall be a highway for the remnant of His people, that shall remain from Assyria, like as there was for Israel in the day that he came up out of the land of Egypt.", "acv": "And there shall be a highway for the remnant of his people, who shall remain, from Assyria, like as there was for Israel in the day that he came up out of the land of Egypt.", "anderson": "", "haweis": "", "noyes": "And it shall be a highway for the remnant of the people, Which shall remain, from Assyria, As there was to Israel, When he came up from the land of Egypt.", "webster": "And there shall be a highway for the remnant of his people, which shall be left, from Assyria; as it was to Israel in the day that he came up from the land of Egypt.", "vulgate": "et erit via residuo populo meo qui relinquetur ab Assyriis sicut fuit Israhel in die qua ascendit de terra Aegypti;", "brenton": "And there shall be a passage for my people that is left in Egypt: and it shall be to Israel as the day when he came forth out of the land of Egypt."}}]}, {"c": 12, "verses": [{"v": 1, "ref": "12:1", "o": "וְ/אָֽמַרְתָּ֙ בַּ/יּ֣וֹם הַ/ה֔וּא אוֹדְ/ךָ֣ יְהוָ֔ה כִּ֥י אָנַ֖פְתָּ בִּ֑/י יָשֹׁ֥ב אַפְּ/ךָ֖ וּֽ/תְנַחֲמֵֽ/נִי", "en": {"kjv": "And in that day thou shalt say, O Lord, I will praise thee: though thou wast angry with me, thine anger is turned away, and thou comfortedst me.", "web": "In that day you will say, “I will give thanks to you, Yahweh; for though you were angry with me, your anger has turned away and you comfort me.", "bsb": "In that day you will say: “O LORD, I will praise You. Although You were angry with me, Your anger has turned away, and You have comforted me.", "asv": "And in that day thou shalt say, I will give thanks unto thee, O Jehovah; for though thou wast angry with me, thine anger is turned away and thou comfortest me.", "ylt": "And thou hast said in that day: `I thank thee, O Jehovah, Though Thou hast been angry with me, Turn back doth Thine anger, And Thou dost comfort me.", "dra": "And thou shalt say in that day: I will give thanks to thee, O Lord, for thou wast angry with me: thy wrath is turned away, and thou hast comforted me.", "bbe": "And in that day you will say I will give praise to you, O Lord; for though you were angry with me, your wrath is turned away, and I am comforted.", "geneva": "And thou shalt say in that day, O Lord, I will prayse thee: though thou wast angrie with me, thy wrath is turned away, and thou comfortest me.", "wycliffe": "And thou schalt seie in that dai, Lord, Y schal knouleche to thee, for thou were wrooth to me; thi strong venieaunce is turned, and thou hast coumfortid me.", "rotherham": "Thou shalt say, therefore, in that day, I will praise thee, O Yahweh! Though thou hast been angry with me, Thine anger turneth back. And thou dost comfort me.", "darby": "And in that day thou shalt say, Jehovah, I will praise thee; for though thou wast angry with me, thine anger is turned away, and thou hast comforted me.", "twenty": "", "jps": "And in that day thou shalt say: 'I will give thanks unto Thee, O HaShem; for though Thou was angry with me, Thine anger is turned away, and Thou comfortest me.", "acv": "And in that day thou shall say, I will give thanks to thee, O Jehovah, for though thou were angry with me. Thine anger is turned away and thou comfort me.", "anderson": "", "haweis": "", "noyes": "In that day shalt thou say, \"I will praise thee, O Jehovah, for, though thou hast been angry with me, Thine anger is turned away, and thou comfortest me.", "webster": "And in that day thou shalt say, O LORD, I will praise thee: though thou wast angry with me, thy anger is turned away, and thou hast comforted me.", "vulgate": "et dices in illa die confitebor tibi Domine quoniam iratus es mihi conversus est furor tuus et consolatus es me;", "brenton": "And in that day thou shalt say, I will bless thee, O Lord; for thou wast angry with me, but thou hast turned aside thy wrath, and hast pitied me."}}, {"v": 2, "ref": "12:2", "o": "הִנֵּ֨ה אֵ֧ל יְשׁוּעָתִ֛/י אֶבְטַ֖ח וְ/לֹ֣א אֶפְחָ֑ד כִּֽי עָזִּ֤/י וְ/זִמְרָת֙ יָ֣הּ יְהוָ֔ה וַֽ/יְהִי לִ֖/י לִֽ/ישׁוּעָֽה", "en": {"kjv": "Behold, God is my salvation; I will trust, and not be afraid: for the Lord Jehovah is my strength and my song; he also is become my salvation.", "web": "Behold, God is my salvation. I will trust, and will not be afraid; for Yah, Yahweh, is my strength and song; and he has become my salvation.”", "bsb": "Surely God is my salvation; I will trust and not be afraid. For the LORD GOD is my strength and my song, and He also has become my salvation.”", "asv": "Behold, God is my salvation; I will trust, and will not be afraid: for Jehovah, even Jehovah, is my strength and song; and he is become my salvation.", "ylt": "Lo, God is my salvation, I trust, and fear not, For my strength and song is Jah Jehovah, And He is to me for salvation.", "dra": "Behold, God is my saviour, I will deal confidently, and will not fear: because the Lord is my strength, and my praise, and he is become my salvation.", "bbe": "See, God is my salvation; I will have faith in the Lord, without fear: for the Lord Jah is my strength and song; and he has become my salvation.", "geneva": "Beholde, God is my saluation: I will trust, and will not feare: for ye Lord God is my strength and song: he also is become my saluation.", "wycliffe": "Lo! God is my sauyour, Y schal do feithfuli, and Y schal not drede. For whi the Lord is my strengthe and my preysyng, and he is maad to me in to helthe.", "rotherham": "Lo, GOD is my salvation! I will trust and not dread,—For, my might and melody, is Yah, Yahweh, And he hath become mine, by salvation.", "darby": "Behold,God is my salvation: I will trust, and not be afraid; for Jah, Jehovah, is my strength and song, and he is become my salvation.", "twenty": "", "jps": "Behold, G-d is my salvation; I will trust, and will not be afraid; for GOD HaShem is my strength and song; and He is become my salvation.'", "acv": "Behold, God is my salvation. I will trust, and will not be afraid, for Jehovah, even Jehovah, is my strength and song, and he has become my salvation.", "anderson": "", "haweis": "", "noyes": "Behold, God is my salvation; I will trust, and will not be afraid; For Jehovah is my glory, and my song; It is he who was my salvation.\"", "webster": "Behold, God [is] my salvation; I will trust, and not be afraid: for the LORD JEHOVAH [is] my strength and [my] song; he also is become my salvation.", "vulgate": "ecce Deus salvator meus fiducialiter agam et non timebo quia fortitudo mea et laus mea Dominus Deus et factus est mihi in salutem;", "brenton": "Behold, my God is my Saviour; I will trust in him, and not be afraid: for the Lord is my glory and my praise, and is become my salvation."}}, {"v": 3, "ref": "12:3", "o": "וּ/שְׁאַבְתֶּם מַ֖יִם בְּ/שָׂשׂ֑וֹן מִ/מַּעַיְנֵ֖י הַ/יְשׁוּעָֽה", "en": {"kjv": "Therefore with joy shall ye draw water out of the wells of salvation.", "web": "Therefore with joy you will draw water out of the wells of salvation.", "bsb": "With joy you will draw water from the springs of salvation,", "asv": "Therefore with joy shall ye draw water out of the wells of salvation.", "ylt": "And ye have drawn waters with joy Out of the fountains of salvation,", "dra": "Thou shall draw waters with joy out of the saviour's fountains:", "bbe": "So with joy will you get water out of the springs of salvation.", "geneva": "Therefore with ioy shall ye drawe waters out of the welles of saluation.", "wycliffe": "Ye schulen drawe watris with ioie of the wellis of the sauyour.", "rotherham": "Therefore shall ye draw water, with rejoicing,—out of the fountains of salvation.", "darby": "And with joy shall ye draw water out of the wells of salvation.", "twenty": "", "jps": "Therefore with joy shall ye draw water out of the wells of salvation.", "acv": "Therefore with joy ye shall draw water out of the wells of salvation.", "anderson": "", "haweis": "", "noyes": "Ye shall draw waters with joy from the fountains of salvation;", "webster": "Therefore with joy shall ye draw water out of the wells of salvation.", "vulgate": "haurietis aquas in gaudio de fontibus salvatoris;", "brenton": "Draw ye therefore water with joy out of the wells of salvation."}}, {"v": 4, "ref": "12:4", "o": "וַ/אֲמַרְתֶּ֞ם בַּ/יּ֣וֹם הַ/ה֗וּא הוֹד֤וּ לַֽ/יהוָה֙ קִרְא֣וּ בִ/שְׁמ֔/וֹ הוֹדִ֥יעוּ בָֽ/עַמִּ֖ים עֲלִֽילֹתָ֑י/ו הַזְכִּ֕ירוּ כִּ֥י נִשְׂגָּ֖ב שְׁמֽ/וֹ", "en": {"kjv": "And in that day shall ye say, Praise the Lord, call upon his name, declare his doings among the people, make mention that his name is exalted.", "web": "In that day you will say, “Give thanks to Yahweh! Call on his name. Declare his doings among the peoples. Proclaim that his name is exalted!", "bsb": "and on that day you will say: “Give praise to the LORD; proclaim His name! Make His works known among the peoples; declare that His name is exalted.", "asv": "And in that day shall ye say, Give thanks unto Jehovah, call upon his name, declare his doings among the peoples, make mention that his name is exalted.", "ylt": "And ye have said in that day, Give ye praise to Jehovah, call in His name. Make known among the peoples His acts. Make mention that set on high is His name.", "dra": "And you shall say in that day: Praise ye the Lord, and call upon his name: make his works known among the people: remember that his name is high.", "bbe": "And in that day you will say, Give praise to the Lord, let his name be honoured, give word of his doings among the peoples, say that his name is lifted up.", "geneva": "And ye shall say in that day, Prayse the Lord: call vpon his Name: declare his workes among the people: make mention of them, for his Name is exalted.", "wycliffe": "And ye schulen seie in that dai, Knouleche ye to the Lord, and clepe ye his name in to help; make ye knowun hise fyndyngis among puplis; haue ye mynde, that his name is hiy.", "rotherham": "And ye shall say in that day, Praise Yahweh. Call upon his Name, Make known among the peoples, his doings,—Bring to remembrance that, exalted, is his Name!", "darby": "And in that day shall ye say, Give ye thanks to Jehovah, call upon his name, declare his deeds among the peoples, make mention that his name is exalted.", "twenty": "", "jps": "And in that day shall ye say: 'Give thanks unto HaShem, proclaim His name, declare His doings among the peoples, make mention that His name is exalted.", "acv": "And in that day ye shall say, Give thanks to Jehovah. Call upon his name. Declare his doings among the peoples. Make mention that his name is exalted.", "anderson": "", "haweis": "", "noyes": "And in that day ye shall say, \"Give thanks to Jehovah; call upon his name; Make known his deeds among the people; Give praises, for his name is exalted!", "webster": "And in that day shall ye say, Praise the LORD, call upon his name, declare his doings among the people, make mention that his name is exalted.", "vulgate": "et dicetis in illa die confitemini Domino et invocate nomen eius notas facite in populis adinventiones eius mementote quoniam excelsum est nomen eius;", "brenton": "And in that day thou shalt say, sing to the Lord, call aloud upon his name, proclaim his glorious deeds among the Gentiles; make mention that his name is exalted."}}, {"v": 5, "ref": "12:5", "o": "זַמְּר֣וּ יְהוָ֔ה כִּ֥י גֵא֖וּת עָשָׂ֑ה מידעת מוּדַ֥עַת זֹ֖את בְּ/כָל הָ/אָֽרֶץ", "en": {"kjv": "Sing unto the Lord; for he hath done excellent things: this is known in all the earth.", "web": "Sing to Yahweh, for he has done excellent things! Let this be known in all the earth!", "bsb": "Sing to the LORD, for He has done glorious things. Let this be known in all the earth.", "asv": "Sing unto Jehovah; for he hath done excellent things: let this be known in all the earth.", "ylt": "Praise ye Jehovah, for excellence He hath done, Known is this in all the earth.", "dra": "Sing ye to the Lord, for he hath done great things: shew this forth in all the earth.", "bbe": "Make a song to the Lord; for he has done noble things: give news of them through all the earth.", "geneva": "Sing vnto the Lord, for he hath done excellent things: this is knowen in all the worlde.", "wycliffe": "Synge ye to the Lord, for he hath do worschipfuli; telle ye this in al erthe.", "rotherham": "Praise in song Yahweh, For a splendid thing, hath he done,—Well known, is this in all the earth.", "darby": "Sing psalms of Jehovah, for he hath done excellent things: this is known in all the earth.", "twenty": "", "jps": "Sing unto HaShem; for He hath done gloriously; this is made known in all the earth.", "acv": "Sing to Jehovah, for he has done excellent things. Let this be known in all the earth.", "anderson": "", "haweis": "", "noyes": "Sing to Jehovah, for he hath done glorious things; Be this known in all the earth!", "webster": "Sing to the LORD; for he hath done excellent things: this [is] known in all the earth.", "vulgate": "cantate Domino quoniam magnifice fecit adnuntiate hoc in universa terra;", "brenton": "Sing praise to the name of the Lord; for he has done great things: declare this in all the earth."}}, {"v": 6, "ref": "12:6", "o": "צַהֲלִ֥י וָ/רֹ֖נִּי יוֹשֶׁ֣בֶת צִיּ֑וֹן כִּֽי גָד֥וֹל בְּ/קִרְבֵּ֖/ךְ קְד֥וֹשׁ יִשְׂרָאֵֽל", "en": {"kjv": "Cry out and shout, thou inhabitant of Zion: for great is the Holy One of Israel in the midst of thee.", "web": "Cry aloud and shout, you inhabitant of Zion; for the Holy One of Israel is great in your midst!”", "bsb": "Cry out and sing, O citizen of Zion, for great among you is the Holy One of Israel.”", "asv": "Cry aloud and shout, thou inhabitant of Zion; for great in the midst of thee is the Holy One of Israel.", "ylt": "Cry aloud, and sing, O inhabitant of Zion, For great in thy midst is the Holy One of Israel!'", "dra": "Rejoice, and praise, O thou habitation of Sion: for great is he that is in the midst of thee, the Holy One of Israel.", "bbe": "Let your voice be sounding in a cry of joy, O daughter of Zion, for great is the Holy One of Israel among you.", "geneva": "Cry out, and shoute, O inhabitant of Zion: for great is ye holy one of Israel in the middes of thee.", "wycliffe": "Thou dwellyng of Syon, make ful out ioie, and preise; for whi the hooli of Israel is greet in the myddis of thee.", "rotherham": "Make shrill thy voice and sing out thou inhabitress of Zion,—That great in the midst of thee, is the Holy One of Israel.", "darby": "Cry out and shout, thou inhabitress of Zion; for great is the Holy One of Israel in the midst of thee.", "twenty": "", "jps": "Cry aloud and shout, thou inhabitant of Zion, for great is the Holy One of Israel in the midst of thee.'", "acv": "Cry aloud and shout, thou inhabitant of Zion, for great in the midst of thee is the Holy One of Israel.", "anderson": "", "haweis": "", "noyes": "Cry aloud, shout for joy, O inhabitant of Zion, For great is the Holy One of Israel in the midst of thee!\"", "webster": "Cry aloud and shout, thou inhabitant of Zion: for great [is] the Holy One of Israel in the midst of thee.", "vulgate": "exulta et lauda habitatio Sion quia magnus in medio tui Sanctus Israhel;", "brenton": "Exalt and rejoice, ye that dwell in Sion: for the Holy One of Israel is exalted in the midst of her."}}]}, {"c": 13, "verses": [{"v": 1, "ref": "13:1", "o": "מַשָּׂ֖א בָּבֶ֑ל אֲשֶׁ֣ר חָזָ֔ה יְשַׁעְיָ֖הוּ בֶּן אָמֽוֹץ", "en": {"kjv": "The burden of Babylon, which Isaiah the son of Amoz did see.", "web": "The burden of Babylon, which Isaiah the son of Amoz saw:", "bsb": "This is the burden against Babylon that Isaiah son of Amoz received:", "asv": "The burden of Babylon, which Isaiah the son of Amoz did see.", "ylt": "The burden of Babylon that Isaiah son of Amoz hath seen:", "dra": "The burden of Babylon which Isaiah the son of Amos saw.", "bbe": "The word of the Lord about Babylon which Isaiah, the son of Amoz, saw.", "geneva": "The burden of Babel, which Isaiah the sonne of Amoz did see.", "wycliffe": "The birthun of Babiloyne, which birthun Ysaie, the sone of Amos, siy.", "rotherham": "The oracle on Babylon,—of which Isaiah, son of Amoz had vision:—", "darby": "The burden of Babylon, which Isaiah the son of Amoz saw.", "twenty": "", "jps": "The burden of Babylon, which Isaiah the son of Amoz did see.", "acv": "The burden of Babylon, which Isaiah the son of Amoz saw.", "anderson": "", "haweis": "", "noyes": "A prophecy concerning Babylon, which Isaiah, the son of Amoz, saw.", "webster": "The burden of Babylon, which Isaiah the son of Amoz saw.", "vulgate": "onus Babylonis quod vidit Isaias filius Amos;", "brenton": "THE VISION WHICH ESAIAS SON OF AMOS SAW AGAINST BABYLON."}}, {"v": 2, "ref": "13:2", "o": "עַ֤ל הַר נִשְׁפֶּה֙ שְֽׂאוּ נֵ֔ס הָרִ֥ימוּ ק֖וֹל לָ/הֶ֑ם הָנִ֣יפוּ יָ֔ד וְ/יָבֹ֖אוּ פִּתְחֵ֥י נְדִיבִֽים", "en": {"kjv": "Lift ye up a banner upon the high mountain, exalt the voice unto them, shake the hand, that they may go into the gates of the nobles.", "web": "Set up a banner on the bare mountain! Lift up your voice to them! Wave your hand, that they may go into the gates of the nobles.", "bsb": "Raise a banner on a barren hilltop; call aloud to them. Wave your hand, that they may enter the gates of the nobles.", "asv": "Set ye up an ensign upon the bare mountain, lift up the voice unto them, wave the hand, that they may go into the gates of the nobles.", "ylt": "`On a high mountain lift ye up an ensign, Raise the voice to them, wave the hand, And they go in to the openings of nobles.", "dra": "Upon the dark mountain lift ye up a banner, exalt the voice, lift up the hand, and let the rulers go into the gates.", "bbe": "Put up a flag on a clear mountain-top, make a loud outcry to them, give directions with the hand, so that they may go into the doors of the great ones.", "geneva": "Lift vp a standard vpon the hie mountaine: lift vp the voyce vnto them: wagge the hand, that they may goe into the gates of the nobles.", "wycliffe": "Reise ye a signe on a myisti hil, and enhaunse ye vois; reise ye the hond, and duykis entre bi the yatis.", "rotherham": "Upon a bare mountain, lift ye up a standard, Raise high the voice to them, Wave the hand, That they may enter the doors of nobles.", "darby": "Lift up a banner upon a bare mountain, raise the voice unto them, shake the hand, that they may enter the gates of the nobles.", "twenty": "", "jps": "Set ye up an ensign upon the high mountain, lift up the voice unto them, wave the hand, that they may go into the gates of the nobles.", "acv": "Set ye up an ensign upon the bare mountain. Lift up the voice to them. Wave the hand, that they may go into the gates of the nobles.", "anderson": "", "haweis": "", "noyes": "Upon the bare mountain lift up a banner; Cry aloud to them, wave the hand, That they may enter the gates of the tyrants!", "webster": "Lift ye up a banner upon the high mountain, exalt the voice to them, shake the hand, that they may go into the gates of the nobles.", "vulgate": "super montem caligosum levate signum exaltate vocem levate manum et ingrediantur portas duces;", "brenton": "Lift up a standard on the mountain of the plain, exalt the voice to them, beckon with the hand, open the gates, ye rulers."}}, {"v": 3, "ref": "13:3", "o": "אֲנִ֥י צִוֵּ֖יתִי לִ/מְקֻדָּשָׁ֑/י גַּ֣ם קָרָ֤אתִי גִבּוֹרַ/י֙ לְ/אַפִּ֔/י עַלִּיזֵ֖י גַּאֲוָתִֽ/י", "en": {"kjv": "I have commanded my sanctified ones, I have also called my mighty ones for mine anger, even them that rejoice in my highness.", "web": "I have commanded my consecrated ones; yes, I have called my mighty men for my anger, even my proudly exulting ones.", "bsb": "I have commanded My sanctified ones; I have even summoned My warriors to execute My wrath and exult in My triumph.", "asv": "I have commanded my consecrated ones, yea, I have called my mighty men for mine anger, even my proudly exulting ones.", "ylt": "I have given charge to My sanctified ones, Also I have called My mighty ones for Mine anger, Those rejoicing at Mine excellency.'", "dra": "I have commanded my sanctified ones, and have called my strong ones in my wrath, them that rejoice in my glory.", "bbe": "I have given orders to my holy ones, I have sent out my men of war, those of mine who take pride in their power, to give effect to my wrath.", "geneva": "I haue commanded them, that I haue sanctified: and I haue called ye mightie to my wrath, and them that reioyce in my glorie.", "wycliffe": "Y haue comaundid to myn halewid men, and Y clepid my stronge men in my wraththe, that maken ful out ioie in my glorie.", "rotherham": "I myself, have given charge to my hallowed ones,—Yea I have called My heroes in showing mine anger, My proudly exulting ones.", "darby": "I have commanded my hallowed ones, I have also called my mighty men for mine anger, them that rejoice in my highness.", "twenty": "", "jps": "I have commanded My consecrated ones, yea, I have called My mighty ones for mine anger, even My proudly exulting ones.", "acv": "I have commanded my consecrated ones, yea, I have called my mighty men for my anger, even my proudly exulting ones.", "anderson": "", "haweis": "", "noyes": "I have given orders to my consecrated ones, Yea, I have called upon my mighty ones to execute mine anger, My proud exulters!", "webster": "I have commanded my sanctified ones, I have also called my mighty ones for my anger, [even] them that rejoice in my highness.", "vulgate": "ego mandavi sanctificatis meis et vocavi fortes meos in ira mea exultantes in gloria mea;", "brenton": "I give command, and I bring them: giants are coming to fulfil my wrath, rejoicing at the same time and insulting."}}, {"v": 4, "ref": "13:4", "o": "ק֥וֹל הָמ֛וֹן בֶּֽ/הָרִ֖ים דְּמ֣וּת עַם רָ֑ב ק֠וֹל שְׁא֞וֹן מַמְלְכ֤וֹת גּוֹיִם֙ נֶֽאֱסָפִ֔ים יְהוָ֣ה צְבָא֔וֹת מְפַקֵּ֖ד צְבָ֥א מִלְחָמָֽה", "en": {"kjv": "The noise of a multitude in the mountains, like as of a great people; a tumultuous noise of the kingdoms of nations gathered together: the Lord of hosts mustereth the host of the battle.", "web": "The noise of a multitude is in the mountains, as of a great people; the noise of an uproar of the kingdoms of the nations gathered together! Yahweh of Armies is mustering the army for the battle.", "bsb": "Listen, a tumult on the mountains, like that of a great multitude! Listen, an uproar among the kingdoms, like nations gathered together! The LORD of Hosts is mobilizing an army for war.", "asv": "The noise of a multitude in the mountains, as of a great people! the noise of a tumult of the kingdoms of the nations gathered together! Jehovah of hosts is mustering the host for the battle.", "ylt": "A voice of a multitude in the mountains, A likeness of a numerous people, A voice of noise from the kingdoms of nations who are gathered, Jehovah of Hosts inspecting a host of battle!", "dra": "The noise of a multitude in the mountains, as it were of many people, the noise of the sound of kings, of nations gathered together: the Lord of hosts hath given charge to the troops of war.", "bbe": "The noise of great numbers in the mountains, like the noise of a strong people! The noise of the kingdoms of the nations meeting together! The Lord of armies is numbering his forces for war.", "geneva": "The noyse of a multitude is in the mountaines, like a great people: a tumultuous voyce of the kingdomes of the nations gathered together: the Lord of hostes nombreth the hoste of the battell.", "wycliffe": "The vois of multitude in hillis, as of many puplis; the vois of sown of kyngis, of hethene men gaderit togidere. The Lord of oostis comaundide to the chyualry of batel,", "rotherham": "The noise of a multitude in the mountains, A resemblance of many people,—The noise of a tumult of kingdoms Nations gathered together, Yahweh of hosts, mustering a host for battle!", "darby": "The noise of a multitude on the mountains, as of a great people; a tumultuous noise of the kingdoms of nations assembled together: Jehovah of hosts mustereth the host of the battle.", "twenty": "", "jps": "Hark, a tumult in the mountains, like as of a great people! Hark, the uproar of the kingdoms of the nations gathered together! HaShem of hosts mustereth the host of the battle.", "acv": "The noise of a multitude in the mountains, as of a great people! The noise of a tumult of the kingdoms of the nations gathered together! Jehovah of hosts is mustering the army for the battle.", "anderson": "", "haweis": "", "noyes": "The noise of a multitude upon the mountains, like that of a great people! The tumultuous noise of kingdoms, of nations gathered together! Jehovah of hosts mustereth his army for battle.", "webster": "The noise of a multitude in the mountains, as of a great people; a tumultuous noise of the kingdoms of nations assembled: the LORD of hosts mustereth the host of the battle.", "vulgate": "vox multitudinis in montibus quasi populorum frequentium vox sonitus regum gentium congregatarum Dominus exercituum praecepit militiae belli;", "brenton": "A voice of many nations on the mountains, even like to that of many nations; a voice of kings and nations gathered together: the Lord of hosts has given command to a war-like nation,"}}, {"v": 5, "ref": "13:5", "o": "בָּאִ֛ים מֵ/אֶ֥רֶץ מֶרְחָ֖ק מִ/קְצֵ֣ה הַ/שָּׁמָ֑יִם יְהוָה֙ וּ/כְלֵ֣י זַעְמ֔/וֹ לְ/חַבֵּ֖ל כָּל הָ/אָֽרֶץ", "en": {"kjv": "They come from a far country, from the end of heaven, even the Lord, and the weapons of his indignation, to destroy the whole land.", "web": "They come from a far country, from the uttermost part of heaven, even Yahweh, and the weapons of his indignation, to destroy the whole land.", "bsb": "They are coming from faraway lands, from the ends of the heavens— the LORD and the weapons of His wrath— to destroy the whole country.", "asv": "They come from a far country, from the uttermost part of heaven, even Jehovah, and the weapons of his indignation, to destroy the whole land.", "ylt": "They are coming in from a land afar off, From the end of the heavens, Jehovah and the instruments of His indignation, To destroy all the land.", "dra": "To them that come from a country afar off, from the end of heaven: the Lord and the instruments of his wrath, to destroy the whole land.", "bbe": "They come from a far country, from the farthest part of heaven, even the Lord and the instruments of his wrath, with destruction for all the land.", "geneva": "They come from a farre countrey, from the end of the heauen: euen the Lord with the weapons of his wrath to destroy the whole land.", "wycliffe": "to men comynge fro a fer lond. The Lord cometh fro the hiynesse of heuene, and the vessels of his strong veniaunce, that he distrie al the lond.", "rotherham": "They are coming in From a land far away. From the utmost bound of the heavens,—Yahweh—with his weapons of indignation, To destroy the land.", "darby": "They come from a far country, from the end of the heavens — Jehovah, and the weapons of his indignation — to destroy the whole land.", "twenty": "", "jps": "They come from a far country, from the end of heaven, even HaShem, and the weapons of His indignation, to destroy the whole earth.", "acv": "They come from a far country, from the outermost part of heaven, even Jehovah, and the weapons of his indignation, to destroy the whole land.", "anderson": "", "haweis": "", "noyes": "They come from a distant country, From the end of Heaven, Jehovah and the instruments of his indignation. To lay waste the whole land.", "webster": "They come from a far country, from the end of heaven, [even] the LORD, and the weapons of his indignation, to destroy the whole land.", "vulgate": "venientibus de terra procul a summitate caeli Dominus et vasa furoris eius ut disperdat omnem terram;", "brenton": "to come from a land afar off, from the utmost foundation of heaven; the Lord and his warriors are coming to destroy all the world."}}, {"v": 6, "ref": "13:6", "o": "הֵילִ֕ילוּ כִּ֥י קָר֖וֹב י֣וֹם יְהוָ֑ה כְּ/שֹׁ֖ד מִ/שַּׁדַּ֥י יָבֽוֹא", "en": {"kjv": "Howl ye; for the day of the Lord is at hand; it shall come as a destruction from the Almighty.", "web": "Wail; for the day of Yahweh is at hand! It will come as destruction from the Almighty.", "bsb": "Wail, for the Day of the LORD is near; it will come as destruction from the Almighty.", "asv": "Wail ye; for the day of Jehovah is at hand; as destruction from the Almighty shall it come.", "ylt": "Howl ye, for near is the day of Jehovah, As destruction from the Mighty it cometh.", "dra": "Howl ye, for the day of the Lord is near: it shall come as a destruction from the Lord.", "bbe": "Send out a cry of grief; for the day of the Lord is near; it comes as destruction from the Most High.", "geneva": "Howle you, for the day of the Lord is at hande: it shall come as a destroier from the Almightie.", "wycliffe": "Yelle ye, for the dai of the Lord is niy; as wastyng it schal come of the Lord.", "rotherham": "Howl ye! for at hand is the day of Yahweh,—As a veritable destruction from the Almighty, shall it come.", "darby": "Howl, for the day of Jehovah is at hand; it cometh as destruction from the Almighty.", "twenty": "", "jps": "Howl ye; for the day of HaShem is at hand; as destruction from the Almighty shall it come.", "acv": "Wail ye, for the day of Jehovah is at hand. It shall come as destruction from the Almighty.", "anderson": "", "haweis": "", "noyes": "Howl ye, for the day of Jehovah is at hand! Like a destruction from the Almighty, it cometh;", "webster": "Howl ye; for the day of the LORD [is] at hand; it shall come as a destruction from the Almighty.", "vulgate": "ululate quia prope est dies Domini quasi vastitas a Domino veniet;", "brenton": "Howl ye, for the day of the Lord is near, and destruction from God shall arrive."}}, {"v": 7, "ref": "13:7", "o": "עַל כֵּ֖ן כָּל יָדַ֣יִם תִּרְפֶּ֑ינָה וְ/כָל לְבַ֥ב אֱנ֖וֹשׁ יִמָּס", "en": {"kjv": "Therefore shall all hands be faint, and every man’s heart shall melt:", "web": "Therefore all hands will be feeble, and everyone’s heart will melt.", "bsb": "Therefore all hands will fall limp, and every man’s heart will melt.", "asv": "Therefore shall all hands be feeble, and every heart of man shall melt:", "ylt": "Therefore, all hands do fail, And every heart of man doth melt.", "dra": "Therefore shall all hands be faint, and every heart of man shall melt,", "bbe": "For this cause all hands will be feeble, and every heart of man be turned to water;", "geneva": "Therefore shall all hands be weakened, and all mens hearts shall melt,", "wycliffe": "For this thing alle hondis schulen be vnmyyti, and eche herte of man schal faile,", "rotherham": "For this cause—All hands, shall hang down,—and Every mortal heart, melt.", "darby": "Therefore shall all hands be feeble, and every heart of man shall melt,", "twenty": "", "jps": "Therefore shall all hands be slack, and every heart of man shall melt.", "acv": "Therefore all hands shall be feeble, and every heart of man shall melt.", "anderson": "", "haweis": "", "noyes": "Therefore shall all hands hang down, And every heart of man shall melt.", "webster": "Therefore shall all hands be faint, and every man's heart shall melt:", "vulgate": "propter hoc omnes manus dissolventur et omne cor hominis tabescet;", "brenton": "Therefore every hand shall become powerless, and every soul of man shall be dismayed."}}, {"v": 8, "ref": "13:8", "o": "וְֽ/נִבְהָ֓לוּ צִירִ֤ים וַֽ/חֲבָלִים֙ יֹֽאחֵז֔וּ/ן כַּ/יּוֹלֵדָ֖ה יְחִיל֑וּ/ן אִ֤ישׁ אֶל רֵעֵ֨/הוּ֙ יִתְמָ֔הוּ פְּנֵ֥י לְהָבִ֖ים פְּנֵי/הֶֽם", "en": {"kjv": "And they shall be afraid: pangs and sorrows shall take hold of them; they shall be in pain as a woman that travaileth: they shall be amazed one at another; their faces shall be as flames.", "web": "They will be dismayed. Pangs and sorrows will seize them. They will be in pain like a woman in labor. They will look in amazement one at another. Their faces will be faces of flame.", "bsb": "Terror, pain, and anguish will seize them; they will writhe like a woman in labor. They will look at one another, their faces flushed with fear.", "asv": "and they shall be dismayed; pangs and sorrows shall take hold of them; they shall be in pain as a woman in travail: they shall look in amazement one at another; their faces shall be faces of flame.", "ylt": "And they have been troubled, Pains and pangs they take, As a travailing woman they are pained, A man at his friend they marvel, The appearance of flames--their faces!", "dra": "And shall be broken. Gripings and pains, shall take hold of them, they shall be in pain as a woman in labour. Every one shall be amazed at his neighbour, their countenances shall be as faces burnt.", "bbe": "Their hearts will be full of fear; pains and sorrows will overcome them; they will be in pain like a woman in childbirth; they will be shocked at one another; their faces will be like flames.", "geneva": "And they shalbe afraid: anguish and sorowe shall take them, and they shall haue paine, as a woman that trauaileth: euery one shall be amased at his neighbour, and their faces shalbe like flames of fire.", "wycliffe": "and schal be al to-brokun. Gnawyngis and sorewis schulen holde Babiloyns; thei schulen haue sorewe, as they that trauelen of child. Ech man schal wondre at his neiybore; her cheris schulen be brent faces.", "rotherham": "And they shall be in distress—Writhings and pains, shall lay hold, As a woman in childbirth, shall they be in pangs,—Everyone, at his neighbour, shall look in amazement, Faces of flames, their faces!", "darby": "and they shall be terrified: pangs and sorrows shall take hold of them, they shall writhe as a woman that travaileth; they shall be amazed one at another, their faces shall be as flames.", "twenty": "", "jps": "And they shall be affrighted; pangs and throes shall take hold them; they shall be in pain as a woman in travail; they shall look aghast one at another; their faces shall be faces of flame.", "acv": "And they shall be dismayed. Pangs and sorrows shall take hold. They shall be in pain as a woman in travail. They shall look in amazement one at another, their faces, faces of flame.", "anderson": "", "haweis": "", "noyes": "They shall be in consternation; Distress and anguish shall lay hold of them; As a woman in travail shall they writhe; They shall look upon one another with amazement: Their faces shall glow like flames.", "webster": "And they shall be afraid: pangs and sorrows shall take hold of them; they shall be in pain as a woman that travaileth: they shall be amazed one at another; their faces [shall be as] flames.", "vulgate": "et conteretur tortiones et dolores tenebunt quasi parturiens dolebunt unusquisque ad proximum suum stupebit facies conbustae vultus eorum;", "brenton": "The elders shall be troubled, and pangs shall seize them, as of a woman in travail: and they shall mourn one to another, and shall be amazed, and shall change their countenance as a flame."}}, {"v": 9, "ref": "13:9", "o": "הִנֵּ֤ה יוֹם יְהוָה֙ בָּ֔א אַכְזָרִ֥י וְ/עֶבְרָ֖ה וַ/חֲר֣וֹן אָ֑ף לָ/שׂ֤וּם הָ/אָ֨רֶץ֙ לְ/שַׁמָּ֔ה וְ/חַטָּאֶ֖י/הָ יַשְׁמִ֥יד מִמֶּֽ/נָּה", "en": {"kjv": "Behold, the day of the Lord cometh, cruel both with wrath and fierce anger, to lay the land desolate: and he shall destroy the sinners thereof out of it.", "web": "Behold, the day of Yahweh comes, cruel, with wrath and fierce anger; to make the land a desolation, and to destroy its sinners out of it.", "bsb": "Behold, the Day of the LORD is coming— cruel, with fury and burning anger— to make the earth a desolation and to destroy the sinners within it.", "asv": "Behold, the day of Jehovah cometh, cruel, with wrath and fierce anger; to make the land a desolation, and to destroy the sinners thereof out of it.", "ylt": "Lo, the day of Jehovah doth come, Fierce, with wrath, and heat of anger, To make the land become a desolation, Yea, its sinning ones He destroyeth from it.", "dra": "Behold, the day of the Lord shall come, a cruel day, and full of indignation, and of wrath, and fury, to lay the land desolate, and to destroy the sinners thereof out of it.", "bbe": "See, the day of the Lord is coming, cruel, with wrath and burning passion: to make the land a waste, driving the sinners in it to destruction.", "geneva": "Beholde, the day of the Lord commeth, cruel, with wrath and fierce anger to lay the land wast: and he shall destroy the sinners out of it.", "wycliffe": "Lo! the dai of the Lord schal come, cruel, and ful of indignacioun, and of wraththe, and of woodnesse; to sette the lond into wildirnesse, and to al to-breke the synneris therof fro that lond.", "rotherham": "Lo! the day of Yahweh, coming in, Fierce and overflowing, and burning with anger,—To devote the earth to desolation, And her sinners, will he destroy out of it.", "darby": "Behold, the day of Jehovah cometh, cruel both with wrath and fierce anger, to lay the earth desolate; and he will destroy the sinners thereof out of it.", "twenty": "", "jps": "Behold, the day of HaShem cometh, cruel, and full of wrath and fierce anger; to make the earth a desolation, and to destroy the sinners thereof out of it,", "acv": "Behold, the day of Jehovah comes, cruel, with wrath and fierce anger, to make the land a desolation, and to destroy the sinners thereof out of it.", "anderson": "", "haweis": "", "noyes": "Behold! the day of Jehovah cometh, Terrible, full of wrath and burning indignation, To make the land a waste, And to destroy the sinners out of it.", "webster": "Behold, the day of the LORD cometh, cruel both with wrath and fierce anger, to lay the land desolate: and he will destroy its sinners out of it.", "vulgate": "ecce dies Domini venit crudelis et indignationis plenus et irae furorisque ad ponendam terram in solitudine et peccatores eius conterendos de ea;", "brenton": "For behold! the day of the Lord is coming which cannot be escaped, a day of wrath and anger, to make the world desolate, and to destroy sinners out of it."}}, {"v": 10, "ref": "13:10", "o": "כִּֽי כוֹכְבֵ֤י הַ/שָּׁמַ֨יִם֙ וּ/כְסִ֣ילֵי/הֶ֔ם לֹ֥א יָהֵ֖לּוּ אוֹרָ֑/ם חָשַׁ֤ךְ הַ/שֶּׁ֨מֶשׁ֙ בְּ/צֵאת֔/וֹ וְ/יָרֵ֖חַ לֹֽא יַגִּ֥יהַ אוֹרֽ/וֹ", "en": {"kjv": "For the stars of heaven and the constellations thereof shall not give their light: the sun shall be darkened in his going forth, and the moon shall not cause her light to shine.", "web": "For the stars of the sky and its constellations will not give their light. The sun will be darkened in its going out, and the moon will not cause its light to shine.", "bsb": "For the stars of heaven and their constellations will not give their light. The rising sun will be darkened, and the moon will not give its light.", "asv": "For the stars of heaven and the constellations thereof shall not give their light; the sun shall be darkened in its going forth, and the moon shall not cause its light to shine.", "ylt": "For the stars of the heavens, and their constellations, Cause not their light to shine, Darkened hath been the sun in its going out, And the moon causeth not its light to come forth.", "dra": "For the stars of heaven, and their brightness shall not display their light: the sun shall be darkened in his rising, and the moon shall not shine with her light.", "bbe": "For the stars of heaven and its bright armies will not give their light: the sun will be made dark in his journey through the heaven, and the moon will keep back her light.", "geneva": "For the starres of heauen and the planets thereof shall not giue their light: the sunne shalbe darkened in his going foorth, and the moone shall not cause her light to shine.", "wycliffe": "For whi the sterris of heuene and the schynyng of tho schulen not sprede abrood her liyt; the sunne is maade derk in his risyng, and the moone schal not schine in hir liyt.", "rotherham": "For the stars of the heavens and their constellations, shall not flash forth their light,—Obscured shall be the sun in his going forth, And the moon, shall not shed her light.", "darby": "For the stars of the heavens and the constellations thereof shall not give their light; the sun shall be darkened in his going forth, and the moon shall not cause her light to shine.", "twenty": "", "jps": "For the stars of heaven and the constellations thereof shall not give their light; the sun shall be darkened in his going forth, and the moon shall not cause her light to shine.", "acv": "For the stars of heaven and the constellations of it shall not give their light. The sun shall be darkened in its going forth, and the moon shall not cause its light to shine.", "anderson": "", "haweis": "", "noyes": "For the stars of heaven, and the constellations thereof, Shall not give their light; The sun shall be darkened at his going forth, And the moon shall withhold her light.", "webster": "For the stars of heaven and its constellations shall not give their light: the sun shall be darkened in his going forth, and the moon shall not cause her light to shine.", "vulgate": "quoniam stellae caeli et splendor earum non expandent lumen suum obtenebratus est sol in ortu suo et luna non splendebit in lumine suo;", "brenton": "For the stars of heaven, and Orion, and all the host of heaven, shall not give their light; and it shall be dark at sunrise, and the moon shall not give her light."}}, {"v": 11, "ref": "13:11", "o": "וּ/פָקַדְתִּ֤י עַל תֵּבֵל֙ רָעָ֔ה וְ/עַל רְשָׁעִ֖ים עֲוֺנָ֑/ם וְ/הִשְׁבַּתִּי֙ גְּא֣וֹן זֵדִ֔ים וְ/גַאֲוַ֥ת עָרִיצִ֖ים אַשְׁפִּֽיל", "en": {"kjv": "And I will punish the world for their evil, and the wicked for their iniquity; and I will cause the arrogancy of the proud to cease, and will lay low the haughtiness of the terrible.", "web": "I will punish the world for their evil, and the wicked for their iniquity. I will cause the arrogance of the proud to cease, and will humble the haughtiness of the terrible.", "bsb": "I will punish the world for its evil and the wicked for their iniquity. I will end the haughtiness of the arrogant and lay low the pride of the ruthless.", "asv": "And I will punish the world for their evil, and the wicked for their iniquity: and I will cause the arrogancy of the proud to cease, and will lay low the haughtiness of the terrible.", "ylt": "And I have appointed on the world evil, And on the wicked their iniquity, And have caused to cease the excellency of the proud, And the excellency of the terrible I make low.", "dra": "And I will visit the evils of the world, and against the wicked for their iniquity: and I will make the pride of infidels to cease, and will bring down the arrogancy of the mighty.", "bbe": "And I will send punishment on the world for its evil, and on the sinners for their wrongdoing; and I will put an end to all pride, and will make low the power of the cruel.", "geneva": "And I will visite the wickednes vpon the worlde, and their iniquitie vpon the wicked, and I wil cause the arrogancie of the proud to cease, and will cast downe the pride of tyrants.", "wycliffe": "And Y schal visite on the yuels of the world, and Y schal visite ayens wickid men the wickidnesse of hem; and Y schal make the pride of vnfeithful men for to reste, and Y schal make low the boost of stronge men.", "rotherham": "And I will visit, upon the inhabited earth, calamity!, And upon the lawless, their punishment, And will quiet the arrogance of the proud, And the loftiness of tyrants, will I lay low.", "darby": "And I will punish the world for evil, and the wicked for their iniquity; and I will make the arrogance of the proud to cease, and will bring low the haughtiness of the violent.", "twenty": "", "jps": "And I will visit upon the world their evil, and upon the wicked their iniquity; and I will cause the arrogancy of the proud to cease, and will lay low the haughtiness of the tyrants.", "acv": "And I will punish the world for the evil, and the wicked for their iniquity. And I will cause the arrogance of the proud to cease, and will lay low the haughtiness of the terrible.", "anderson": "", "haweis": "", "noyes": "For I will punish the world for its guilt, And the wicked for their iniquity. I will put an end to the arrogance of the proud, And I will bring down the haughtiness of the tyrants.", "webster": "And I will punish the world for [their] evil, and the wicked for their iniquity; and I will cause the arrogance of the proud to cease, and will lay low the haughtiness of the terrible.", "vulgate": "et visitabo super orbis mala et contra impios iniquitatem eorum et quiescere faciam superbiam infidelium et arrogantiam fortium humiliabo;", "brenton": "And I will command evils for the whole world, and will visit their sins on the ungodly: and I will destroy the pride of transgressors, and will bring low the pride of the haughty."}}, {"v": 12, "ref": "13:12", "o": "אוֹקִ֥יר אֱנ֖וֹשׁ מִ/פָּ֑ז וְ/אָדָ֖ם מִ/כֶּ֥תֶם אוֹפִֽיר", "en": {"kjv": "I will make a man more precious than fine gold; even a man than the golden wedge of Ophir.", "web": "I will make people more rare than fine gold, even a person than the pure gold of Ophir.", "bsb": "I will make man scarcer than pure gold, and mankind rarer than the gold of Ophir.", "asv": "I will make a man more rare than fine gold, even a man than the pure gold of Ophir.", "ylt": "I make man more rare than fine gold, And a common man than pure gold of Ophir.", "dra": "A man shall be more precious than gold, yea a man than the finest of gold.", "bbe": "I will make men so small in number, that a man will be harder to get than gold, even the best gold of Ophir.", "geneva": "I will make a man more precious then fine golde, euen a man aboue the wedge of golde of Ophir.", "wycliffe": "A man of ful age schal be preciousere than gold, and a man schal be preciousere than pure gold and schynyng.", "rotherham": "I will cause, a man, to be more precious than fine gold,—Even a son of earth than, the finest gold of Ophir.", "darby": "I will make a man more precious than fine gold, even man than the gold of Ophir.", "twenty": "", "jps": "I will make man more rare than fine gold, even man than the pure gold of Ophir.", "acv": "I will make a man more rare than fine gold, even a man than the pure gold of Ophir.", "anderson": "", "haweis": "", "noyes": "I will make men scarcer than gold; Yea, men than the gold of Ophir.", "webster": "I will make a man more precious than fine gold; even a man than the golden wedge of Ophir.", "vulgate": "pretiosior erit vir auro et homo mundo obrizo;", "brenton": "And they that are left shall be more precious than gold tried in the fire; and a man shall be more precious than the stone that is in Suphir."}}, {"v": 13, "ref": "13:13", "o": "עַל כֵּן֙ שָׁמַ֣יִם אַרְגִּ֔יז וְ/תִרְעַ֥שׁ הָ/אָ֖רֶץ מִ/מְּקוֹמָ֑/הּ בְּ/עֶבְרַת֙ יְהוָ֣ה צְבָא֔וֹת וּ/בְ/י֖וֹם חֲר֥וֹן אַפּֽ/וֹ", "en": {"kjv": "Therefore I will shake the heavens, and the earth shall remove out of her place, in the wrath of the Lord of hosts, and in the day of his fierce anger.", "web": "Therefore I will make the heavens tremble, and the earth will be shaken out of its place in the wrath of Yahweh of Armies, and in the day of his fierce anger.", "bsb": "Therefore I will make the heavens tremble, and the earth will be shaken from its place at the wrath of the LORD of Hosts on the day of His burning anger.", "asv": "Therefore I will make the heavens to tremble, and the earth shall be shaken out of its place, in the wrath of Jehovah of hosts, and in the day of his fierce anger.", "ylt": "Therefore the heavens I cause to tremble, And the earth doth shake from its place, In the wrath of Jehovah of Hosts, And in a day of the heat of his anger.", "dra": "For this I will trouble the heaven: and the earth shall be moved out of her place, for the indignation of the Lord of hosts, and for the day of his fierce wrath.", "bbe": "For this cause the heavens will be shaking, and the earth will be moved out of its place, in the wrath of the Lord of armies, and in the day of his burning passion.", "geneva": "Therefore I will shake the heauen, and the earth shall remooue out of her place in the wrath of the Lord of hostes, and in the day of his fierce anger.", "wycliffe": "On this thing I schal disturble heuene, and the erthe schal be moued fro his place; for the indignacioun of the Lord of oostis, and for the dai of wraththe of his strong veniaunce.", "rotherham": "For this cause, the heavens, will I disturb, And, the earth, shall tremble out of her place,—In the wrath of Yahweh of hosts, And in the day of the glow of his anger.", "darby": "Therefore I will make the heavens to shake, and the earth shall be removed out of her place, at the wrath of Jehovah of hosts, and in the day of his fierce anger.", "twenty": "", "jps": "Therefore I will make the heavens to tremble, and the earth shall be shaken out of her place, for the wrath of HaShem of hosts, and for the day of His fierce anger.", "acv": "Therefore I will make the heavens to tremble, and the earth shall be shaken out of its place, in the wrath of Jehovah of hosts, and in the day of his fierce anger.", "anderson": "", "haweis": "", "noyes": "Therefore I will make the heavens tremble, And the earth shall be shaken out of her place, In the anger of Jehovah of hosts, In the day of his burning indignation.", "webster": "Therefore I will shake the heavens, and the earth shall remove out of her place, in the wrath of the LORD of hosts, and in the day of his fierce anger.", "vulgate": "super hoc caelum turbabo et movebitur terra de loco suo propter indignationem Domini exercituum et propter diem irae furoris eius;", "brenton": "For the heaven shall be enraged, and the earth shall be shaken from her foundation, because of the fierce anger of the Lord of hosts, in the day in which his wrath shall come on."}}, {"v": 14, "ref": "13:14", "o": "וְ/הָיָה֙ כִּ/צְבִ֣י מֻדָּ֔ח וּ/כְ/צֹ֖אן וְ/אֵ֣ין מְקַבֵּ֑ץ אִ֤ישׁ אֶל עַמּ/וֹ֙ יִפְנ֔וּ וְ/אִ֥ישׁ אֶל אַרְצ֖/וֹ יָנֽוּסוּ", "en": {"kjv": "And it shall be as the chased roe, and as a sheep that no man taketh up: they shall every man turn to his own people, and flee every one into his own land.", "web": "It will happen that like a hunted gazelle, and like sheep that no one gathers, they will each turn to their own people, and will each flee to their own land.", "bsb": "Like a hunted gazelle, like a sheep without a shepherd, each will return to his own people, each will flee to his native land.", "asv": "And it shall come to pass, that as the chased roe, and as sheep that no man gathereth, they shall turn every man to his own people, and shall flee every man to his own land.", "ylt": "And it hath been, as a roe driven away, And as a flock that hath no gatherer, Each unto his people--they turn, And each unto his land--they flee.", "dra": "And they shall be as a doe fleeing away, and as a sheep: and there shall be none to gather them together: every man shall turn to his own people, and every one shall flee to his own land.", "bbe": "And it will be that, like a roe in flight, and like wandering sheep, they will go every man to his people and to his land.", "geneva": "And it shall be as a chased doe, and as a sheepe that no man taketh vp. euery man shall turne to his owne people, and flee eche one to his owne lande.", "wycliffe": "And it schal be as a doo fleynge, and as a scheep, and noon schal be that schal gadere togidere; ech man schal turne to his puple, and alle bi hem silf schulen fle to her lond.", "rotherham": "And it shall be—Like a gazelle that is chased, And like a sheep with none to lift it up,—Each, to his own people, will they turn, And, each, to his own land, will they flee:", "darby": "And it shall be as with a chased roe, and as with a flock that no man gathereth together; every one shall turn to his own people, and every one flee into his own land.", "twenty": "", "jps": "And it shall come to pass, that as the chased gazelle, and as sheep that no man gathereth, they shall turn every man to his own people, and shall flee every man to his own land.", "acv": "And it shall come to pass, that as the chased roe, and as sheep that no man gathers, they shall turn every man to his own people, and shall flee every man to his own land.", "anderson": "", "haweis": "", "noyes": "Then shall they be like a chased doe; Like a flock, which no one gathereth together; Every one shall turn to his own people, And every one flee to his own land.", "webster": "And it shall be as the chased roe, and as a sheep that no man taketh up: they shall every man turn to his own people, and flee every one to his own land.", "vulgate": "et erit quasi dammula fugiens et quasi ovis et non erit qui congreget unusquisque ad populum suum convertetur et singuli ad terram suam fugient;", "brenton": "And they that are left shall be as a fleeing fawn, and as a stray sheep, and there shall be none to gather them: so that a man shall turn back to his people, and a man shall flee to his own land."}}, {"v": 15, "ref": "13:15", "o": "כָּל הַ/נִּמְצָ֖א יִדָּקֵ֑ר וְ/כָל הַ/נִּסְפֶּ֖ה יִפּ֥וֹל בֶּ/חָֽרֶב", "en": {"kjv": "Every one that is found shall be thrust through; and every one that is joined unto them shall fall by the sword.", "web": "Everyone who is found will be thrust through. Everyone who is captured will fall by the sword.", "bsb": "Whoever is caught will be stabbed, and whoever is captured will die by the sword.", "asv": "Every one that is found shall be thrust through; and every one that is taken shall fall by the sword.", "ylt": "Every one who is found is thrust through, And every one who is added falleth by sword.", "dra": "Every one that shall be found, shall be slain: and every one that shall come to their aid, shall fall by the sword.", "bbe": "Everyone who is overtaken will have a spear put through him, and everyone who goes in flight will be put to the sword.", "geneva": "Euery one that is founde, shall be striken through: and whosoeuer ioyneth himselfe, shall fal by the sworde.", "wycliffe": "Ech man that is foundun, schal be slayn; and ech man that cometh aboue, schal falle doun bi swerd.", "rotherham": "Every one found, shall be thrust through,—And, every one taken, shall fall by the sword;", "darby": "All that are found shall be thrust through; and every one that is in league [with them] shall fall by the sword.", "twenty": "", "jps": "Every one that is found shall be thrust through; and every one that is caught shall fall by the sword.", "acv": "Everyone who is found shall be thrust through, and everyone who is taken shall fall by the sword.", "anderson": "", "haweis": "", "noyes": "Every one that is overtaken shall be thrust through, And every one that is caught shall fall by the sword.", "webster": "Every one that is found shall be thrust through; and every one that is joined [to them] shall fall by the sword.", "vulgate": "omnis qui inventus fuerit occidetur et omnis qui supervenerit cadet in gladio;", "brenton": "For whosoever shall be taken shall be overcome; and they that are gathered together shall fall by the sword."}}, {"v": 16, "ref": "13:16", "o": "וְ/עֹלְלֵי/הֶ֥ם יְרֻטְּשׁ֖וּ לְ/עֵֽינֵי/הֶ֑ם יִשַּׁ֨סּוּ֙ בָּֽתֵּי/הֶ֔ם וּ/נְשֵׁי/הֶ֖ם תשגלנה תִּשָּׁכַֽבְנָה", "en": {"kjv": "Their children also shall be dashed to pieces before their eyes; their houses shall be spoiled, and their wives ravished.", "web": "Their infants also will be dashed in pieces before their eyes. Their houses will be ransacked, and their wives raped.", "bsb": "Their infants will be dashed to pieces before their eyes, their houses will be looted, and their wives will be ravished.", "asv": "Their infants also shall be dashed in pieces before their eyes; their houses shall be rifled, and their wives ravished.", "ylt": "And their sucklings are dashed to pieces before their eyes, Spoiled are their houses, and their wives lain with.", "dra": "Their inhabitants shall be dashed in pieces before their eyes: their houses shall be pillaged, and their wives shall be ravished.", "bbe": "Their young children will be broken up before their eyes; their goods will be taken away, and their wives made the property of others.", "geneva": "Their children also shall be broken in pieces before their eyes: their houses shall be spoiled, and their wiues rauished.", "wycliffe": "The yonge children of them schulen be hurtlid doun bifore the iyen of them; her housis schulen be rauischid, and her wyues schulen be defoulid.", "rotherham": "And, their infants, shall be dashed to the ground, before their eyes,—Plundered shall be, their houses, and their wives ravished.", "darby": "And their infants shall be dashed in pieces before their eyes, their houses shall be rifled, and their women ravished.", "twenty": "", "jps": "Their babes also shall be dashed in pieces before their eyes; their houses shall be spoiled, and their wives ravished.", "acv": "Their infants also shall be dashed in pieces before their eyes. Their houses shall be rifled, and their wives ravished.", "anderson": "", "haweis": "", "noyes": "Their children shall be dashed to pieces before their eyes; Their houses shall be plundered, and their wives ravished.", "webster": "Their children also shall be dashed to pieces before their eyes; their houses shall be plundered, and their wives ravished.", "vulgate": "infantes eorum adlident in oculis eorum diripientur domus eorum et uxores eorum violabuntur;", "brenton": "And they shall dash their children before their eyes; and they shall spoil their houses, and shall take their wives."}}, {"v": 17, "ref": "13:17", "o": "הִנְ/נִ֛י מֵעִ֥יר עֲלֵי/הֶ֖ם אֶת מָדָ֑י אֲשֶׁר כֶּ֨סֶף֙ לֹ֣א יַחְשֹׁ֔בוּ וְ/זָהָ֖ב לֹ֥א יַחְפְּצוּ בֽ/וֹ", "en": {"kjv": "Behold, I will stir up the Medes against them, which shall not regard silver; and as for gold, they shall not delight in it.", "web": "Behold, I will stir up the Medes against them, who will not value silver, and as for gold, they will not delight in it.", "bsb": "Behold, I will stir up against them the Medes, who have no regard for silver and no desire for gold.", "asv": "Behold, I will stir up the Medes against them, who shall not regard silver, and as for gold, they shall not delight in it.", "ylt": "Lo, I am stirring up against them the Medes, Who silver esteem not, And gold--they delight not in it.", "dra": "Behold I will stir up the Medes against them, who shall not seek silver, nor desire gold:", "bbe": "See, I am driving the Medes against them, who put no value on silver and have no pleasure in gold.", "geneva": "Beholde, I will stirre vp the Medes against them, which shall not regarde siluer, nor be desirous of golde.", "wycliffe": "Lo! Y schal reise on them Medeis, that seken not siluer, nethir wolen gold;", "rotherham": "Behold me! stirring up against them the Medes,—Who of silver, shall take no account, And as for gold, they shall not delight in it;", "darby": "Behold, I will stir up the Medes against them, who do not regard silver, and as for gold, they have no delight in it.", "twenty": "", "jps": "Behold, I will stir up the Medes against them, who shall not regard silver, and as for gold, they shall not delight in it.", "acv": "Behold, I will stir up the Medes against them, who shall not regard silver, and as for gold, they shall not delight in it.", "anderson": "", "haweis": "", "noyes": "Behold, I stir up against them the Medes, Who make no account of silver, And as to gold, they do not regard it.", "webster": "Behold, I will stir up the Medes against them, who shall not regard silver; and [as for] gold, they shall not delight in it.", "vulgate": "ecce ego suscitabo super eos Medos qui argentum non quaerant nec aurum velint;", "brenton": "Behold, I will stir up against you the Medes, who do not regard silver, neither have they need of gold."}}, {"v": 18, "ref": "13:18", "o": "וּ/קְשָׁת֖וֹת נְעָרִ֣ים תְּרַטַּ֑שְׁנָה וּ/פְרִי בֶ֨טֶן֙ לֹ֣א יְרַחֵ֔מוּ עַל בָּנִ֖ים לֹֽא תָח֥וּס עֵינָֽ/ם", "en": {"kjv": "Their bows also shall dash the young men to pieces; and they shall have no pity on the fruit of the womb; their eye shall not spare children.", "web": "Their bows will dash the young men in pieces; and they shall have no pity on the fruit of the womb. Their eyes will not spare children.", "bsb": "Their bows will dash young men to pieces; they will have no mercy on the fruit of the womb; they will not look with pity on the children.", "asv": "Andtheirbows shall dash the young men in pieces; and they shall have no pity on the fruit of the womb; their eye shall not spare children.", "ylt": "And bows dash young men to pieces, And the fruit of the womb they pity not, On sons their eye hath no pity.", "dra": "But with their arrows they shall kill the children, and shall have no pity upon the sucklings of the womb, and their eye shall not spare their sons.", "bbe": "In their hands are bows and spears; they are cruel, violently putting the young men to death, and crushing the young women; they have no pity for children, and no mercy for the fruit of the body.", "geneva": "With bowes also shall they destroy ye children, and shall haue no compassion vpon the fruit of the wombe, and their eies shall not spare the children.", "wycliffe": "but thei shulen sle litle children bi arowis, and thei schulen not haue merci on wombis yyuynge mylk, and the iye of them schal not spare on sones.", "rotherham": "And, bows, shall dash the young to pieces,—And on the fruit of the womb, will they have no pity, Over children, will their eye throw no shield.", "darby": "And [their] bows shall dash the young men to pieces, and they shall have no pity on the fruit of the womb: their eye shall not spare children.", "twenty": "", "jps": "And their bows shall dash the young men in pieces; and they shall have no pity on the fruit of the womb; their eye shall not spare children.", "acv": "And their bows shall dash the young men in pieces. And they shall have no pity on the fruit of the womb; their eye shall not spare children.", "anderson": "", "haweis": "", "noyes": "Their bows shall strike down the young men, And on the fruit of the womb they shall have no compassion; Their eye shall not pity the children.", "webster": "[Their] bows also shall dash the young men to pieces; and they shall have no pity on the fruit of the womb; their eye shall not spare children.", "vulgate": "sed sagittis parvulos interficiant et lactantibus uteri non misereantur et super filios non parcat oculus eorum;", "brenton": "They shall break the bows of the young men; and they shall have no mercy on your children; nor shall their eyes spare thy children."}}, {"v": 19, "ref": "13:19", "o": "וְ/הָיְתָ֤ה בָבֶל֙ צְבִ֣י מַמְלָכ֔וֹת תִּפְאֶ֖רֶת גְּא֣וֹן כַּשְׂדִּ֑ים כְּ/מַהְפֵּכַ֣ת אֱלֹהִ֔ים אֶת סְדֹ֖ם וְ/אֶת עֲמֹרָֽה", "en": {"kjv": "And Babylon, the glory of kingdoms, the beauty of the Chaldees’ excellency, shall be as when God overthrew Sodom and Gomorrah.", "web": "Babylon, the glory of kingdoms, the beauty of the Chaldeans’ pride, will be like when God overthrew Sodom and Gomorrah.", "bsb": "And Babylon, the jewel of the kingdoms, the glory of the pride of the Chaldeans, will be overthrown by God like Sodom and Gomorrah.", "asv": "And Babylon, the glory of kingdoms, the beauty of the Chaldeans’ pride, shall be as when God overthrew Sodom and Gomorrah.", "ylt": "And Babylon, the beauty of kingdoms, The glory, the excellency of the Chaldeans, Hath been as overthrown by God, With Sodom and with Gomorrah.", "dra": "And that Babylon, glorious among kingdoms, the famous pride of the Chaldeans, shall be even as the Lord destroyed Sodom and Gomorrha.", "bbe": "And Babylon, the glory of kingdoms, the beautiful town which is the pride of the Chaldaeans, will be like God's destruction of Sodom and Gomorrah.", "geneva": "And Babel the glorie of kingdomes, the beautie and pride of the Chaldeans, shall be as the destruction of God in Sodom and Gomorah.", "wycliffe": "And Babiloyne, thilke gloriouse citee in rewmes, noble in the pride of Caldeis, schal be destried, as God destried Sodom and Gomore.", "rotherham": "Thus shall Babylon—The most lovely of kingdoms, The majestic beauty of the Chaldees—Become as in the divine overthrow of Sodom and Gomorrah.", "darby": "And Babylon, the glory of kingdoms, the beauty of the Chaldeans' pride, shall be as whenGod overthrew Sodom and Gomorrah.", "twenty": "", "jps": "And Babylon, the glory of kingdoms, the beauty of the Chaldeans' pride, shall be as when G-d overthrew Sodom and Gomorrah.", "acv": "And Babylon, the glory of kingdoms, the beauty of the Chaldeans' pride, shall be as when God overthrew Sodom and Gomorrah.", "anderson": "", "haweis": "", "noyes": "So shall Babylon, the glory of kingdoms, The proud ornament of the Chaldeans, Be like Sodom and Gomorrah, which God overthrew,", "webster": "And Babylon, the glory of kingdoms, the beauty of the Chaldees' excellence, shall be as when God overthrew Sodom and Gomorrah.", "vulgate": "et erit Babylon illa gloriosa in regnis inclita in superbia Chaldeorum sicut subvertit Deus Sodomam et Gomorram;", "brenton": "And Babylon, which is called glorious by the king of the Chaldeans, shall be as when God overthrew Sodoma, and Gomorrha."}}, {"v": 20, "ref": "13:20", "o": "לֹֽא תֵשֵׁ֣ב לָ/נֶ֔צַח וְ/לֹ֥א תִשְׁכֹּ֖ן עַד דּ֣וֹר וָ/ד֑וֹר וְ/לֹֽא יַהֵ֥ל שָׁם֙ עֲרָבִ֔י וְ/רֹעִ֖ים לֹא יַרְבִּ֥צוּ שָֽׁם", "en": {"kjv": "It shall never be inhabited, neither shall it be dwelt in from generation to generation: neither shall the Arabian pitch tent there; neither shall the shepherds make their fold there.", "web": "It will never be inhabited, neither will it be lived in from generation to generation. The Arabian will not pitch a tent there, neither will shepherds make their flocks lie down there.", "bsb": "She will never be inhabited or settled from generation to generation; no nomad will pitch his tent there, no shepherd will rest his flock there.", "asv": "It shall never be inhabited, neither shall it be dwelt in from generation to generation: neither shall the Arabian pitch tent there; neither shall shepherds make their flocks to lie down there.", "ylt": "She doth not sit for ever, Nor continueth unto many generations, Nor doth Arab pitch tent there, And shepherds lie not down there.", "dra": "It shall no more be inhabited for ever, and it shall not be founded unto generation and generation: neither shall the Arabian pitch his tents there, nor shall shepherds rest there.", "bbe": "People will never be living in it again, and it will have no more men from generation to generation: the Arab will not put up his tent there; and those who keep sheep will not make it a resting-place for their flocks.", "geneva": "It shall not bee inhabited for euer, neither shall it be dwelled in from generation to generation: neither shall the Arabian pitch his tents there, neither shall the shepheardes make their foldes there.", "wycliffe": "It shall not be enhabitid til in to the ende, and it schal not be foundid til to generacioun and generacioun; a man of Arabie schal not sette tentis there, and scheepherdis schulen not reste there.", "rotherham": "It shall not be dwelt in for ever, Neither shall it be inhabited from generation to generation,—Neither shall encamp there, an Arab, Nor, shepherds, fold their flocks there.", "darby": "It shall never be inhabited, neither shall it be dwelt in, even to generation and generation; nor shall Arabian pitch tent there, nor shepherds make fold there.", "twenty": "", "jps": "It shall never be inhabited, neither shall it be dwelt in from generation to generation; neither shall the Arabian pitch tent there; neither shall the shepherds make their fold there.", "acv": "It shall never be inhabited, nor shall it be dwelt in from generation to generation. Neither shall the Arabian pitch tent there, nor shall shepherds make their flocks to lie down there.", "anderson": "", "haweis": "", "noyes": "It shall never more be inhabited; Nor shall it be dwelt in through all generations. Nor shall the Arabian pitch his tent there, Nor shall shepherds make their folds there.", "webster": "It shall never be inhabited, neither shall it be dwelt in from generation to generation: neither shall the Arabian pitch tent there; neither shall the shepherds make their fold there.", "vulgate": "non habitabitur usque in finem et non fundabitur usque ad generationem et generationem nec ponet ibi tentoria Arabs nec pastores requiescent ibi;", "brenton": "It shall never be inhabited, neither shall any enter into it for many generations: neither shall the Arabians pass through it; nor shall shepherds at all rest in it."}}, {"v": 21, "ref": "13:21", "o": "וְ/רָבְצוּ שָׁ֣ם צִיִּ֔ים וּ/מָלְא֥וּ בָתֵּי/הֶ֖ם אֹחִ֑ים וְ/שָׁ֤כְנוּ שָׁם֙ בְּנ֣וֹת יַֽעֲנָ֔ה וּ/שְׂעִירִ֖ים יְרַקְּדוּ שָֽׁם", "en": {"kjv": "But wild beasts of the desert shall lie there; and their houses shall be full of doleful creatures; and owls shall dwell there, and satyrs shall dance there.", "web": "But wild animals of the desert will lie there, and their houses will be full of jackals. Ostriches will dwell there, and wild goats will frolic there.", "bsb": "But desert creatures will lie down there, and howling creatures will fill her houses. Ostriches will dwell there, and wild goats will leap about.", "asv": "But wild beasts of the desert shall lie there; and their houses shall be full of doleful creatures; and ostriches shall dwell there, and wild goats shall dance there.", "ylt": "And Ziim have lain down there, And full have been their houses of howlings, And dwelt there have daughters of an ostrich, And goats do skip there.", "dra": "But wild beasts shall rest there, and their houses shall be filled with serpents, and ostriches shall dwell there, and the hairy ones shall dance there:", "bbe": "But the beasts of the waste land will have their holes there; and the houses will be full of crying jackals, and ostriches will have their place there, and evil spirits will be dancing there.", "geneva": "But Ziim shall lodge there, and their houses shall be ful of Ohim: Ostriches shall dwel there, and the Satyrs shall dance there.", "wycliffe": "But wielde beestis schulen reste there, and the housis of hem schulen be fillid with dragouns; and ostrichis schulen dwelle there, and heeri beestis schulen skippe there.", "rotherham": "Then shall lie down there, wild beasts, And filled shall be their houses with owls,—Then shall inhabit there, the ostrich, And shaggy creatures, shall dance there.", "darby": "But beasts of the desert shall lie there, and their houses shall be full of owls; and ostriches shall dwell there, and wild goats shall dance there.", "twenty": "", "jps": "But wild-cats shall lie there; and their houses shall be full of ferrets; and ostriches shall dwell there, and satyrs shall dance there.", "acv": "But wild beasts of the desert shall lie there, and their houses shall be full of doleful creatures. And ostriches shall dwell there, and wild goats shall dance there.", "anderson": "", "haweis": "", "noyes": "But there shall the wild beasts of the desert lodge, And owls shall fill their houses; And ostriches shall dwell there, And satyrs shall dance there.", "webster": "But wild beasts of the desert shall lie there; and their houses shall be full of doleful creatures; and owls shall dwell there, and satyrs shall dance there.", "vulgate": "sed requiescent ibi bestiae et replebuntur domus eorum draconibus et habitabunt ibi strutiones et pilosi saltabunt ibi;", "brenton": "But wild beasts shall rest there; and the houses shall be filled with howling; and monsters shall rest there, and devils shall dance there, and satyrs shall dwell there; and hedgehogs shall make their nests in their houses. It will come soon, and will not tarry."}}, {"v": 22, "ref": "13:22", "o": "וְ/עָנָ֤ה אִיִּים֙ בְּ/אַלְמנוֹתָ֔י/ו וְ/תַנִּ֖ים בְּ/הֵ֣יכְלֵי עֹ֑נֶג וְ/קָר֤וֹב לָ/בוֹא֙ עִתָּ֔/הּ וְ/יָמֶ֖י/הָ לֹ֥א יִמָּשֵֽׁכוּ", "en": {"kjv": "And the wild beasts of the islands shall cry in their desolate houses, and dragons in their pleasant palaces: and her time is near to come, and her days shall not be prolonged.", "web": "Wolves will cry in their castles, and jackals in the pleasant palaces. Her time is near to come, and her days will not be prolonged.", "bsb": "Hyenas will howl in her fortresses and jackals in her luxurious palaces. Babylon’s time is at hand, and her days will not be prolonged.", "asv": "And wolves shall cry in their castles, and jackals in the pleasant palaces: and her time is near to come, and her days shall not be prolonged.", "ylt": "And Aiim have responded in his forsaken habitations, And dragons in palaces of delight, And near to come is her time, And her days are not drawn out!", "dra": "And owls shall answer one another there, in the houses thereof, and sirens in the temples of pleasure.", "bbe": "And wolves will be answering one another in their towers, and jackals in their houses of pleasure: her time is near, and her days of power will quickly be ended.", "geneva": "And Iim shall crie in their palaces, and dragons in their pleasant palaces: and the time thereof is readie to come, and the daies thereof shall not be prolonged.", "wycliffe": "And bitouris schulen answere there in the housis therof, and fliynge serpentis in the templis of lust.", "rotherham": "And jackals shall answer, in their citadels, And wild dogs, in their voluptuous palaces,—And near to come is her time, And, her days, shall not be delayed.", "darby": "And jackals shall cry to one another in their palaces, and wild dogs in the pleasant castles. And her time is near to come, and her days shall not be prolonged.", "twenty": "", "jps": "And jackals shall howl in their castles, and wild-dogs in the pleasant palaces; and her time is near to come, and her days shall not be prolonged.", "acv": "And wolves shall cry in their castles, and jackals in the pleasant palaces. And her time is near to come, and her days shall not be prolonged.", "anderson": "", "haweis": "", "noyes": "Wolves shall howl in their palaces, And jackals in their pleasant edifices. Her time is near, And her days shall not be prolonged.", "webster": "And the wild beasts of the isles shall cry in their desolate houses, and dragons in [their] pleasant palaces: and her time [is] near to come, and her days shall not be prolonged.", "vulgate": "et respondebunt ibi ululae in aedibus eius et sirenae in delubris voluptatis;", "brenton": ""}}]}, {"c": 14, "verses": [{"v": 1, "ref": "14:1", "o": "כִּי֩ יְרַחֵ֨ם יְהוָ֜ה אֶֽת יַעֲקֹ֗ב וּ/בָחַ֥ר עוֹד֙ בְּ/יִשְׂרָאֵ֔ל וְ/הִנִּיחָ֖/ם עַל אַדְמָתָ֑/ם וְ/נִלְוָ֤ה הַ/גֵּר֙ עֲלֵי/הֶ֔ם וְ/נִסְפְּח֖וּ עַל בֵּ֥ית יַעֲקֹֽב", "en": {"kjv": "For the Lord will have mercy on Jacob, and will yet choose Israel, and set them in their own land: and the strangers shall be joined with them, and they shall cleave to the house of Jacob.", "web": "For Yahweh will have compassion on Jacob, and will yet choose Israel, and set them in their own land. The foreigner will join himself with them, and they will unite with the house of Jacob.", "bsb": "For the LORD will have compassion on Jacob; once again He will choose Israel and settle them in their own land. The foreigner will join them and unite with the house of Jacob.", "asv": "For Jehovah will have compassion on Jacob, and will yet choose Israel, and set them in their own land: and the sojourner shall join himself with them, and they shall cleave to the house of Jacob.", "ylt": "Because Jehovah loveth Jacob, And hath fixed again on Israel, And given them rest on their own land, And joined hath been the sojourner to them, And they have been admitted to the house of Jacob.", "dra": "Her time is near at hand, and her days shall not be prolonged. For the Lord will have mercy on Jacob, and will yet choose out of Israel, and will make them rest upon their own ground: and the stranger shall be joined with them, and shall adhere to the house of Jacob.", "bbe": "For the Lord will have mercy on Jacob, and will again make Israel his special people, and will put them in their land; and the man from a strange country will take his place among them and be joined to the family of Jacob.", "geneva": "For the Lord wil haue compassion of Iaakob, and wil yet chuse Israel, and cause them to rest in their owne lande: and the stranger shall ioyne him selfe vnto them, and they shall cleaue to the house of Iaakob.", "wycliffe": "It is niy that the tyme therof come, and the daies therof schulen not be maad fer; for whi the Lord schal haue merci of Jacob, and he schal chese yit of Israel, and schal make them for to reste on her lond; a comelyng schal be ioyned to them, and schal cleue to the house of Jacob.", "rotherham": "For Yahweh will have compassion on Jacob, And will yet choose Israel, And will give them rest upon their own soil,—And the sojourner, shall join himself, unto them, And they shall attach themselves unto the house of Jacob;", "darby": "For Jehovah will have mercy on Jacob, and will yet choose Israel, and set them in rest in their own land; and the stranger shall be united to them, and they shall be joined to the house of Jacob.", "twenty": "", "jps": "For HaShem will have compassion on Jacob, and will yet choose Israel, and set them in their own land; and the stranger shall join himself with them, and they shall cleave to the house of Jacob.", "acv": "For Jehovah will have compassion on Jacob, and will yet choose Israel, and set them in their own land. And the sojourner shall join himself with them, and they shall cling to the house of Jacob.", "anderson": "", "haweis": "", "noyes": "For Jehovah will have compassion upon Jacob, And will again set his love upon Israel, And cause them to rest in his own land. And strangers shall join themselves to them, And cleave to the house of Jacob.", "webster": "For the LORD will have mercy on Jacob, and will yet choose Israel, and set them in their own land: and the strangers shall be joined with them, and they shall cleave to the house of Jacob.", "vulgate": "prope est ut veniat tempus eius et dies eius non elongabuntur miserebitur enim Dominus Iacob et eliget adhuc de Israhel et requiescere eos faciet super humum suam adiungetur advena ad eos et adherebit domui Iacob;", "brenton": "And the Lord will have mercy on Jacob, and will yet choose Israel, and they shall rest on their land: and the stranger shall be added to them, yea, shall be added to the house of Jacob."}}, {"v": 2, "ref": "14:2", "o": "וּ/לְקָח֣וּ/ם עַמִּים֮ וֶ/הֱבִיא֣וּ/ם אֶל מְקוֹמָ/ם֒ וְ/הִֽתְנַחֲל֣וּ/ם בֵּֽית יִשְׂרָאֵ֗ל עַ֚ל אַדְמַ֣ת יְהוָ֔ה לַ/עֲבָדִ֖ים וְ/לִ/שְׁפָח֑וֹת וְ/הָיוּ֙ שֹׁבִ֣ים לְ/שֹֽׁבֵי/הֶ֔ם וְ/רָד֖וּ בְּ/נֹגְשֵׂי/הֶֽם", "en": {"kjv": "And the people shall take them, and bring them to their place: and the house of Israel shall possess them in the land of the Lord for servants and handmaids: and they shall take them captives, whose captives they were; and they shall rule over their oppressors.", "web": "The peoples will take them, and bring them to their place. The house of Israel will possess them in Yahweh’s land for servants and for handmaids. They will take as captives those whose captives they were; and they shall rule over their oppressors.", "bsb": "The nations will escort Israel and bring it to its homeland. Then the house of Israel will possess the nations as menservants and maidservants in the LORD’s land. They will make captives of their captors and rule over their oppressors.", "asv": "And the peoples shall take them, and bring them to their place; and the house of Israel shall possess them in the land of Jehovah for servants and for handmaids: and they shall take them captive whose captives they were; and they shall rule over their oppressors.", "ylt": "And peoples have taken them, And have brought them in unto their place, And the house of Israel have inherited them, On the land of Jehovah, For men-servants and for maid-servants, And they have been captors of their captors, And have ruled over their exactors.", "dra": "And the people shall take them, and bring them into their place: and the house of Israel shall possess them in the land of the Lord for servants and handmaids: and they shall make them captives that had taken them, and shall subdue their oppressors.", "bbe": "And the people will take them with them to their place: and the children of Israel will give them a heritage in the Lord's land as men-servants and women-servants, making them prisoners whose prisoners they were; and they will be rulers over their masters.", "geneva": "And the people shall receiue them and bring them to their owne place, and the house of Israel shall possesse them in the land of the Lord, for seruants and handmaids: and they shall take them prisoners, whose captiues they were, and haue rule ouer their oppressours.", "wycliffe": "And puplis schulen holde hem, and schulen brynge hem in to her place. And the hous of Israel schal haue hem in possessioun in to seruauntis and handmaidis on the lond of the Lord; and thei schulen take tho men that token hem, and thei schulen make suget her wrongful axeris.", "rotherham": "And peoples shall take them, and bring them into their own place, And the house of Israel shall possess themselves of them upon the soil of Yahweh for servants and for handmaids,—Thus shall they be taking captive their captors, And shall tread down their oppressors.", "darby": "And the peoples shall take them and bring them to their place; and the house of Israel shall possess them in the land of Jehovah for servants and handmaids; and they shall take them captive whose captives they were, and they shall rule over their oppressors.", "twenty": "", "jps": "And the peoples shall take them, and bring them to their place; and the house of Israel shall possess them in the land of HaShem for servants and for handmaids; and they shall take them captive, whose captives they were; and they shall rule over their oppressors.", "acv": "And the peoples shall take them, and bring them to their place. And the house of Israel shall possess them in the land of Jehovah for servants and for handmaids. And they shall take them captive whose captives they were, and they shall rule over their oppressors.", "anderson": "", "haweis": "", "noyes": "The nations shall take them and bring them to their own place; And the house of Israel shall possess them, in the land of Jehovah, As servants and as handmaids; They shall take captive their captors, And they shall rule over their oppressors.", "webster": "And the people shall take them, and bring them to their place: and the house of Israel shall possess them in the land of the LORD for servants and handmaids: and they shall take them captives, whose captives they were; and they shall rule over their oppressors.", "vulgate": "et tenebunt eos populi et adducent eos in locum suum et possidebit eos domus Israhel super terram Domini in servos et ancillas et erunt capientes eos qui se ceperant et subicient exactores suos;", "brenton": "And the Gentiles shall take them, and bring them into their place: and they shall inherit them, and they shall be multiplied upon the land for servants and handmaidens: and they that took them captives shall become captives to them; and they that had lordship over them shall be under their rule."}}, {"v": 3, "ref": "14:3", "o": "וְ/הָיָ֗ה בְּ/י֨וֹם הָנִ֤יחַ יְהוָה֙ לְ/ךָ֔ מֵֽ/עָצְבְּ/ךָ֖ וּ/מֵ/רָגְזֶ֑/ךָ וּ/מִן הָ/עֲבֹדָ֥ה הַ/קָּשָׁ֖ה אֲשֶׁ֥ר עֻבַּד בָּֽ/ךְ", "en": {"kjv": "And it shall come to pass in the day that the Lord shall give thee rest from thy sorrow, and from thy fear, and from the hard bondage wherein thou wast made to serve,", "web": "It will happen in the day that Yahweh will give you rest from your sorrow, from your trouble, and from the hard service in which you were made to serve,", "bsb": "On the day that the LORD gives you rest from your pain and torment, and from the hard labor into which you were forced,", "asv": "And it shall come to pass in the day that Jehovah shall give thee rest from thy sorrow, and from thy trouble, and from the hard service wherein thou wast made to serve,", "ylt": "And it hath come to pass, In the day of Jehovah's giving rest to thee, From thy grief, and from thy trouble, And from the sharp bondage, That hath been served upon thee,", "dra": "And it shall come to pass in that day, that when God shall give thee rest from thy labour, and from thy vexation, and from the hard bondage, wherewith thou didst serve before,", "bbe": "And it will be, in the day when the Lord gives you rest from your sorrow, and from your trouble, and from the hard yoke which they had put on you,", "geneva": "And in that day when the Lord shall giue thee rest from thy sorrow, and from thy feare, and from the sore bodage, wherein thou didest serue,", "wycliffe": "And it schal be in that dai, whanne God schal yyue to thee reste of thi trauel, and of thi shakyng, and of hard seruage, in which thou seruedist bifore,", "rotherham": "And it shall come to pass, in the day when Yahweh shall give thee rest from thy toil, and from thy disquiet,—and from the hard service which had been laid upon thee,", "darby": "And it shall come to pass in the day that Jehovah shall give thee rest from thy sorrow and from thy trouble and from the hard bondage wherein thou wast made to serve,", "twenty": "", "jps": "And it shall come to pass in the day that HaShem shall give thee rest from thy travail, and from thy trouble, and from the hard service wherein thou wast made to serve,", "acv": "And it shall come to pass in the day that Jehovah shall give thee rest from thy sorrow, and from thy trouble, and from the hard service in which thou were made to serve,", "anderson": "", "haweis": "", "noyes": "So when Jehovah shall have given thee rest From thy sorrow and thy distress, And from the hard bondage Which was laid upon thee,", "webster": "And it shall come to pass in the day that the LORD shall give thee rest from thy sorrow, and from thy fear, and from the hard bondage in which thou wast made to serve,", "vulgate": "et erit in die illa cum requiem dederit tibi Deus a labore tuo et a concussione tua et a servitute dura qua ante servisti;", "brenton": "And it shall come to pass in that day, that the Lord shall give thee rest from thy sorrow and vexation, and from thy hard servitude wherein thou didst serve them."}}, {"v": 4, "ref": "14:4", "o": "וְ/נָשָׂ֜אתָ הַ/מָּשָׁ֥ל הַ/זֶּ֛ה עַל מֶ֥לֶךְ בָּבֶ֖ל וְ/אָמָ֑רְתָּ אֵ֚יךְ שָׁבַ֣ת נֹגֵ֔שׂ שָׁבְתָ֖ה מַדְהֵבָֽה", "en": {"kjv": "That thou shalt take up this proverb against the king of Babylon, and say, How hath the oppressor ceased! the golden city ceased!", "web": "that you will take up this parable against the king of Babylon, and say, “How the oppressor has ceased! The golden city has ceased!”", "bsb": "you will sing this song of contempt against the king of Babylon: How the oppressor has ceased, and how his fury has ended!", "asv": "that thou shalt take up this parable against the king of Babylon, and say, How hath the oppressor ceased! the golden city ceased!", "ylt": "That thou hast taken up this simile Concerning the king of Babylon, and said, How hath the exactor ceased,", "dra": "Thou shalt take up this parable against the king of Babylon, and shalt say: How is the oppressor come to nothing, the tribute hath ceased?", "bbe": "That you will take up this bitter song against the king of Babylon, and say, How has the cruel overseer come to an end! He who was lifted up in pride is cut off;", "geneva": "Then shalt thou take vp this prouerbe against the King of Babel, and say, Howe hath the oppressor ceased? and the gold thirsty Babel rested?", "wycliffe": "thou schalt take this parable ayens the kyng of Babiloyne, and thou schalt sei, Hou ceesside the wrongful axere, restide tribute?", "rotherham": "that thou shalt take up this taunt over the king of Babylon, and shalt say:—How hath ceased the oppressor! Ceased the exactress!", "darby": "that thou shalt take up this proverb against the king of Babylon, and say, How hath the oppressor ceased, — the exactress of gold ceased!", "twenty": "", "jps": "that thou shalt take up this parable against the king of Babylon, and say: How hath the oppressor ceased! the exactress of gold ceased!", "acv": "that thou shall take up this taunt against the king of Babylon, and say, How has the oppressor ceased, the golden city ceased!", "anderson": "", "haweis": "", "noyes": "Then shall thou utter this song over the king of Babylon, and say, \"How hath the tyrant fallen, The oppression ceased!", "webster": "That thou shalt take up this proverb against the king of Babylon, and say, How hath the oppressor ceased! the golden city ceased!", "vulgate": "sumes parabolam istam contra regem Babylonis et dices quomodo cessavit exactor quievit tributum;", "brenton": "And thou shalt take up this lamentation against the king of Babylon, How has the extortioner ceased, and the taskmaster ceased!"}}, {"v": 5, "ref": "14:5", "o": "שָׁבַ֥ר יְהוָ֖ה מַטֵּ֣ה רְשָׁעִ֑ים שֵׁ֖בֶט מֹשְׁלִֽים", "en": {"kjv": "The Lord hath broken the staff of the wicked, and the sceptre of the rulers.", "web": "Yahweh has broken the staff of the wicked, the scepter of the rulers,", "bsb": "The LORD has broken the staff of the wicked, the scepter of the rulers.", "asv": "Jehovah hath broken the staff of the wicked, the sceptre of the rulers;", "ylt": "Ceased hath the golden one. Broken hath Jehovah the staff of the wicked, The sceptre of rulers.", "dra": "The Lord hath broken the staff of the wicked, the rod of the rulers,", "bbe": "The stick of the evil-doers, the rod of the rulers, is broken by the Lord;", "geneva": "The Lord hath broken the rodde of the wicked, and the scepter of the rulers:", "wycliffe": "The Lord hath al to-broke the staf of wickid men, the yerde of lordis,", "rotherham": "Broke hath Yahweh the staff of the lawless,—The sceptre of despots;", "darby": "Jehovah hath broken the staff of the wicked, the sceptre of the rulers.", "twenty": "", "jps": "HaShem hath broken the staff of the wicked, the sceptre of the rulers,", "acv": "Jehovah has broken the staff of the wicked, the scepter of the rulers,", "anderson": "", "haweis": "", "noyes": "Jehovah hath broken the staff of the wicked, The rod of the tyrants,", "webster": "The LORD hath broken the staff of the wicked, [and] the scepter of the rulers.", "vulgate": "contrivit Dominus baculum impiorum virgam dominantium;", "brenton": "The Lord has broken the yoke of sinners, the yoke of princes."}}, {"v": 6, "ref": "14:6", "o": "מַכֶּ֤ה עַמִּים֙ בְּ/עֶבְרָ֔ה מַכַּ֖ת בִּלְתִּ֣י סָרָ֑ה רֹדֶ֤ה בָ/אַף֙ גּוֹיִ֔ם מֻרְדָּ֖ף בְּלִ֥י חָשָֽׂךְ", "en": {"kjv": "He who smote the people in wrath with a continual stroke, he that ruled the nations in anger, is persecuted, and none hindereth.", "web": "who struck the peoples in wrath with a continual stroke, who ruled the nations in anger, with a persecution that no one restrained.", "bsb": "It struck the peoples in anger with unceasing blows; it subdued the nations in rage with relentless persecution.", "asv": "that smote the peoples in wrath with a continual stroke, that ruled the nations in anger, with a persecution that none restrained.", "ylt": "He who is smiting peoples in wrath, A smiting without intermission, He who is ruling in anger nations, Pursuing without restraint!", "dra": "That struck the people in wrath with an incurable wound, that brought nations under in fury, that persecuted in a cruel manner.", "bbe": "He whose rod was on the peoples with an unending wrath, ruling the nations in passion, with an uncontrolled rule.", "geneva": "Which smote the people in anger with a continuall plague, and ruled the nations in wrath: if any were persecuted, he did not let.", "wycliffe": "that beet puplis in indignacioun, with vncurable wounde, that sugetide folkis in woodnesse, that pursuede cruely.", "rotherham": "Smiting peoples in passion With stroke unremitting,—Trampling, in anger, on nations, Persecution unhindered.", "darby": "He that smote the peoples in wrath with a relentless stroke, he that ruled the nations in anger, is persecuted unsparingly.", "twenty": "", "jps": "That smote the peoples in wrath with an incessant stroke, that ruled the nations in anger, with a persecution that none restrained.", "acv": "who smote the peoples in wrath with a continual stroke, who ruled the nations in anger, with a persecution that none restrained.", "anderson": "", "haweis": "", "noyes": "That smote the people in anger, With a continual stroke, That lorded it over the nations in wrath With unremitted oppression.", "webster": "He who smote the people in wrath with a continual stroke, he that ruled the nations in anger, is persecuted, [and] none hindereth.", "vulgate": "caedentem populos in indignatione plaga insanabili subicientem in furore gentes persequentem crudeliter;", "brenton": "Having smitten a nation in wrath, with an incurable plague, smiting a nation with a wrathful plague, which spared them not, he rested in quiet."}}, {"v": 7, "ref": "14:7", "o": "נָ֥חָה שָׁקְטָ֖ה כָּל הָ/אָ֑רֶץ פָּצְח֖וּ רִנָּֽה", "en": {"kjv": "The whole earth is at rest, and is quiet: they break forth into singing.", "web": "The whole earth is at rest, and is quiet. They break out song.", "bsb": "All the earth is at peace and at rest; they break out in song.", "asv": "The whole earth is at rest, and is quiet: they break forth into singing.", "ylt": "At rest--quiet hath been all the earth, They have broken forth into singing.", "dra": "The whole earth is quiet and still, it is glad and hath rejoiced.", "bbe": "All the earth is at rest and is quiet: they are bursting into song.", "geneva": "The whole worlde is at rest and is quiet: they sing for ioye.", "wycliffe": "Ech lond restide, and was stille; it was ioiful, and made ful out ioie.", "rotherham": "Quiet, at rest, the whole earth,—Men have burst into shouting!", "darby": "The whole earth is at rest, is quiet: they break forth into singing.", "twenty": "", "jps": "The whole earth is at rest, and is quiet; they break forth into singing.", "acv": "The whole earth is at rest, and is quiet. They break forth into singing.", "anderson": "", "haweis": "", "noyes": "The whole earth is at rest, is quiet; They break forth into singing.", "webster": "The whole earth is at rest, [and] is quiet: they break forth into singing.", "vulgate": "conquievit et siluit omnis terra gavisa est et exultavit;", "brenton": "All the earth cries aloud with joy:"}}, {"v": 8, "ref": "14:8", "o": "גַּם בְּרוֹשִׁ֛ים שָׂמְח֥וּ לְ/ךָ֖ אַרְזֵ֣י לְבָנ֑וֹן מֵ/אָ֣ז שָׁכַ֔בְתָּ לֹֽא יַעֲלֶ֥ה הַ/כֹּרֵ֖ת עָלֵֽי/נוּ", "en": {"kjv": "Yea, the fir trees rejoice at thee, and the cedars of Lebanon, saying, Since thou art laid down, no feller is come up against us.", "web": "Yes, the fir trees rejoice with you, with the cedars of Lebanon, saying, “Since you are humbled, no lumberjack has come up against us.”", "bsb": "Even the cypresses and cedars of Lebanon exult over you: “Since you have been laid low, no woodcutter comes against us.”", "asv": "Yea, the fir-trees rejoice at thee, and the cedars of Lebanon, saying, Since thou art laid low, no hewer is come up against us.", "ylt": "Even firs have rejoiced over thee, Cedars of Lebanon-- saying : Since thou hast lain down, The hewer cometh not up against us.", "dra": "The fir trees also have rejoiced over thee, and the cedars of Libanus, saying: Since thou hast slept, there hath none come up to cut us down.", "bbe": "Even the trees of the wood are glad over you, the trees of Lebanon, saying, From the time of your fall no wood-cutter has come up against us with an axe.", "geneva": "Also the firre trees reioyced of thee, and the cedars of Lebanon, saying, Since thou art laid downe, no hewer came vp against vs.", "wycliffe": "Also fir trees and cedris of the Liban weren glad on thee; sithen thou sleptist, noon stieth that kittith vs doun.", "rotherham": "Yea the pine-trees, make mirth at thee, Cedars of Lebanon, Since thou wast laid low, No feller hath come up against us!", "darby": "Even the cypresses rejoice at thee, the cedars of Lebanon, [saying,] Since thou art laid down, no feller is come up against us.", "twenty": "", "jps": "Yea, the cypresses rejoice at thee, and the cedars of Lebanon: 'Since thou art laid down, no feller is come up against us.'", "acv": "Yea, the fir trees rejoice at thee, and the cedars of Lebanon, saying, Since thou are laid low, no hewer has come up against us.", "anderson": "", "haweis": "", "noyes": "Even the cypress-trees exult over thee, And the cedars of Lebanon: ‘Since thou art fallen, No feller cometh up against us.’", "webster": "Yes, the fir-trees rejoice at thee, [and] the cedars of Lebanon, [saying], Since thou art laid down, no feller is come up against us.", "vulgate": "abietes quoque laetatae sunt super te et cedri Libani ex quo dormisti non ascendit qui succidat nos;", "brenton": "the trees also of Libanus rejoice against thee, and the cedar of Libanus, saying, From the time that thou hast been laid low, no one has come up to cut us down."}}, {"v": 9, "ref": "14:9", "o": "שְׁא֗וֹל מִ/תַּ֛חַת רָגְזָ֥ה לְ/ךָ֖ לִ/קְרַ֣את בּוֹאֶ֑/ךָ עוֹרֵ֨ר לְ/ךָ֤ רְפָאִים֙ כָּל עַתּ֣וּדֵי אָ֔רֶץ הֵקִים֙ מִ/כִּסְאוֹתָ֔/ם כֹּ֖ל מַלְכֵ֥י גוֹיִֽם", "en": {"kjv": "Hell from beneath is moved for thee to meet thee at thy coming: it stirreth up the dead for thee, even all the chief ones of the earth; it hath raised up from their thrones all the kings of the nations.", "web": "Sheol from beneath has moved for you to meet you at your coming. It stirs up the departed spirits for you, even all the rulers of the earth. It has raised up from their thrones all the kings of the nations.", "bsb": "Sheol beneath is eager to meet you upon your arrival. It stirs the spirits of the dead to greet you— all the rulers of the earth. It makes all the kings of the nations rise from their thrones.", "asv": "Sheol from beneath is moved for thee to meet thee at thy coming; it stirreth up the dead for thee, even all the chief ones of the earth; it hath raised up from their thrones all the kings of the nations.", "ylt": "Sheol beneath hath been troubled at thee, To meet thy coming in, It is waking up for thee Rephaim, All chiefs ones of earth, It hath raised up from their thrones All kings of nations.", "dra": "Hell below was in an uproar to meet thee at thy coming, it stirred up the giants for thee. All the princes of the earth are risen up from their thrones, all the princes of nations.", "bbe": "The underworld is moved at your coming: the shades of the dead are awake before you, even the strong ones of the earth; all the kings of the world have got up from their seats.", "geneva": "Hel beneath is mooued for thee to meete thee at thy comming, raising vp the deade for thee, euen all the princes of the earth, and hath raised from their thrones all the Kinges of the nations.", "wycliffe": "Helle vndur thee is disturblid for the meeting of thi comyng; he schal reise giauntis to thee; alle the princes of erthe han rise fro her seetis, alle the princes of naciouns.", "rotherham": "Hades beneath, is excited about thee To meet thine arrival,—Rousing up, for thee Shades, All the he-goats of earth! Maketh rise from their thrones, All the kings of the nations.", "darby": "Sheol from beneath is moved for thee to meet [thee] at thy coming, stirring up the dead for thee, all the he-goats of the earth; making to rise from their thrones all the kings of the nations.", "twenty": "", "jps": "The nether-world from beneath is moved for thee to meet thee at thy coming; the shades are stirred up for thee, even all the chief ones of the earth; all the kings of the nations are raised up from their thrones.", "acv": "Sheol from beneath is moved for thee, to meet thee at thy coming. It stirs up the dead for thee, even all the chief ones of the earth. It has raised up from their thrones all the kings of the nations.", "anderson": "", "haweis": "", "noyes": "The under-world is in commotion on account of thee, To meet thee at thy coming; It stirreth up before thee the shades, all the mighty of the earth; It arouseth from their thrones all the kings of the nations;", "webster": "Hell from beneath is moved for thee to meet [thee] at thy coming: it stirreth up the dead for thee, [even] all the chief ones of the earth; it hath raised up from their thrones all the kings of the nations.", "vulgate": "infernus subter conturbatus est in occursum adventus tui suscitavit tibi gigantas omnes principes terrae surrexerunt de soliis suis omnes principes nationum;", "brenton": "Hell from beneath is provoked to meet thee: all the great ones that have ruled over the earth have risen up together against thee, they that have raised up from their thrones all the kings of the nations."}}, {"v": 10, "ref": "14:10", "o": "כֻּלָּ֣/ם יַֽעֲנ֔וּ וְ/יֹאמְר֖וּ אֵלֶ֑י/ךָ גַּם אַתָּ֛ה חֻלֵּ֥יתָ כָמ֖וֹ/נוּ אֵלֵ֥י/נוּ נִמְשָֽׁלְתָּ", "en": {"kjv": "All they shall speak and say unto thee, Art thou also become weak as we? art thou become like unto us?", "web": "They all will answer and ask you, “Have you also become as weak as we are? Have you become like us?”", "bsb": "They will all respond to you, saying, “You too have become weak, as we are; you have become like us!”", "asv": "All they shall answer and say unto thee, Art thou also become weak as we? art thou become like unto us?", "ylt": "All of them answer and say unto thee, Even thou hast become weak like us! Unto us thou hast become like!", "dra": "All shall answer, and say to thee: Thou also art wounded as well as we, thou art become like unto us.", "bbe": "They all make answer and say to you, Have you become feeble like us? have you been made even as we are?", "geneva": "All they shall crie, and saie vnto thee, Art thou become weake also as we? art thou become like vnto vs?", "wycliffe": "Alle thei schulen answere, and thei shulen seie to thee, And thou art woundid as and we, thou art maad lijk vs.", "rotherham": "All of them, answer, and say to thee,—Thou too, made strengthless, as we! Unto us, art thou like!", "darby": "All of them shall answer and say unto thee, Art thou also become powerless as we; art thou become like unto us!", "twenty": "", "jps": "All they do answer and say unto thee: 'Art thou also become weak as we? Art thou become like unto us?", "acv": "They shall all answer and say to thee, Have thou also become weak as we? Have thou become like us?", "anderson": "", "haweis": "", "noyes": "They all accost thee, and say, ‘Art thou, too, become weak as we? Art thou become like us?’", "webster": "All they shall speak and say to thee, Art thou also become weak as we? Art thou become like us?", "vulgate": "universi respondebunt et dicent tibi et tu vulneratus es sicut nos nostri similis effectus es;", "brenton": "All shall answer and say to thee, Thou also hast been taken, even as we; and thou art numbered amongst us."}}, {"v": 11, "ref": "14:11", "o": "הוּרַ֥ד שְׁא֛וֹל גְּאוֹנֶ֖/ךָ הֶמְיַ֣ת נְבָלֶ֑י/ךָ תַּחְתֶּ֨י/ךָ֙ יֻצַּ֣ע רִמָּ֔ה וּ/מְכַסֶּ֖י/ךָ תּוֹלֵעָֽה", "en": {"kjv": "Thy pomp is brought down to the grave, and the noise of thy viols: the worm is spread under thee, and the worms cover thee.", "web": "Your pomp is brought down to Sheol, with the sound of your stringed instruments. Maggots are spread out under you, and worms cover you.", "bsb": "Your pomp has been brought down to Sheol, along with the music of your harps. Maggots are your bed and worms your blanket.", "asv": "Thy pomp is brought down to Sheol, and the noise of thy viols: the worm is spread under thee, and worms cover thee.", "ylt": "Brought down to Sheol hath been thine excellency, The noise of thy psaltery, Under thee spread out hath been the worm, Yea, covering thee is the worm.", "dra": "Thy pride is brought down to hell, thy carcass is fallen down: under thee shall the moth be strewed, and worms shall be thy covering.", "bbe": "Your pride has gone down into the underworld, and the noise of your instruments of music; the worms are under you, and your body is covered with them.", "geneva": "Thy pompe is brought downe to ye graue, and the sounde of thy violes: the worme is spred vnder thee, and the wormes couer thee.", "wycliffe": "Thi pride is drawun doun to hellis, thi deed careyn felle doun; a mouyte schal be strewyd vndur thee, and thin hilyng schal be wormes.", "rotherham": "Brought down to Hades, thy pride. The hum of thy harps, Beneath thee, is spread out corruption, And, thy coverlet—worms!", "darby": "— Thy pomp is brought down to Sheol, the noise of thy lyres: the maggot is spread under thee, and worms cover thee.", "twenty": "", "jps": "Thy pomp is brought down to the nether-world, and the noise of thy psalteries; the maggot is spread under thee, and the worms cover thee.'", "acv": "Thy pomp is brought down to Sheol, and the noise of thy viols. The worm is spread under thee, and worms cover thee.", "anderson": "", "haweis": "", "noyes": "Thy pomp is brought down to the grave, And the sound of thy harps. Vermin have become thy couch, And worms thy covering.", "webster": "Thy pomp is brought down to the grave, [and] the noise of thy viols: the worm is spread under thee, and the worms cover thee.", "vulgate": "detracta est ad inferos superbia tua concidit cadaver tuum subter te sternetur tinea et operimentum tuum erunt vermes;", "brenton": "Thy glory has come down to Hades, and thy great mirth: under thee they shall spread corruption, and the worm shall be thy covering."}}, {"v": 12, "ref": "14:12", "o": "אֵ֛יךְ נָפַ֥לְתָּ מִ/שָּׁמַ֖יִם הֵילֵ֣ל בֶּן שָׁ֑חַר נִגְדַּ֣עְתָּ לָ/אָ֔רֶץ חוֹלֵ֖שׁ עַל גּוֹיִֽם", "en": {"kjv": "How art thou fallen from heaven, O Lucifer, son of the morning! how art thou cut down to the ground, which didst weaken the nations!", "web": "How you have fallen from heaven, morning star, son of the dawn! How you are cut down to the ground, who laid the nations low!", "bsb": "How you have fallen from heaven, O day star, son of the dawn! You have been cut down to the ground, O destroyer of nations.", "asv": "How art thou fallen from heaven, O day-star, son of the morning! how art thou cut down to the ground, that didst lay low the nations!", "ylt": "How hast thou fallen from the heavens, O shining one, son of the dawn! Thou hast been cut down to earth, O weakener of nations.", "dra": "How art thou fallen from heaven, O Lucifer, who didst rise in the morning? how art thou fallen to the earth, that didst wound the nations?", "bbe": "How great is your fall from heaven, O shining one, son of the morning! How are you cut down to the earth, low among the dead bodies!", "geneva": "How art thou fallen from heauen, O Lucifer, sonne of the morning? and cutte downe to the grounde, which didest cast lottes vpon the nations?", "wycliffe": "A! Lucifer, that risidist eerli, hou feldist thou doun fro heuene; thou that woundist folkis, feldist doun togidere in to erthe.", "rotherham": "How hast thou fallen from heaven, O Shining One—Son of the Dawn! Hewn down to the earth, O crusher of nations!", "darby": "How art thou fallen from heaven, Lucifer, son of the morning! Thou art cut down to the ground, that didst prostrate the nations!", "twenty": "", "jps": "How art thou fallen from heaven, O day-star, son of the morning! How art thou cut down to the ground, that didst cast lots over the nations!", "acv": "How thou are fallen from heaven, O day-star, son of the morning! How thou are cut down to the ground, who laid the nations low!", "anderson": "", "haweis": "", "noyes": "How art thou fallen from heaven, O Lucifer, son of the morning! How art thou cast down to the ground, Thou that didst trample upon the nations!", "webster": "How art thou fallen from heaven, O Lucifer, son of the morning! [how] art thou cut down to the ground, which didst weaken the nations!", "vulgate": "quomodo cecidisti de caelo lucifer qui mane oriebaris corruisti in terram qui vulnerabas gentes;", "brenton": "How has Lucifer, that rose in the morning, fallen from heaven! He that sent orders to all the nations is crushed to the earth."}}, {"v": 13, "ref": "14:13", "o": "וְ/אַתָּ֞ה אָמַ֤רְתָּ בִֽ/לְבָבְ/ךָ֙ הַ/שָּׁמַ֣יִם אֶֽעֱלֶ֔ה מִ/מַּ֥עַל לְ/כֽוֹכְבֵי אֵ֖ל אָרִ֣ים כִּסְאִ֑/י וְ/אֵשֵׁ֥ב בְּ/הַר מוֹעֵ֖ד בְּ/יַרְכְּתֵ֥י צָפֽוֹן", "en": {"kjv": "For thou hast said in thine heart, I will ascend into heaven, I will exalt my throne above the stars of God: I will sit also upon the mount of the congregation, in the sides of the north:", "web": "You said in your heart, “I will ascend into heaven! I will exalt my throne above the stars of God! I will sit on the mountain of assembly, in the far north!", "bsb": "You said in your heart: “I will ascend to the heavens; I will raise my throne above the stars of God. I will sit on the mount of assembly, in the far reaches of the north.", "asv": "And thou saidst in thy heart, I will ascend into heaven, I will exalt my throne above the stars of God; and I will sit upon the mount of congregation, in the uttermost parts of the north;", "ylt": "And thou saidst in thy heart: the heavens I go up, Above stars of God I raise my throne, And I sit in the mount of meeting in the sides of the north.", "dra": "And thou saidst in thy heart: I will ascend into heaven, I will exalt my throne above the stars of God, I will sit in the mountain of the covenant, in the sides of the north.", "bbe": "For you said in your heart, I will go up to heaven, I will make my seat higher than the stars of God; I will take my place on the mountain of the meeting-place of the gods, in the inmost parts of the north.", "geneva": "Yet thou saidest in thine heart, I will ascende into heauen, and exalt my throne aboue beside the starres of God: I will sitte also vpon the mount of the Congregation in the sides of the North.", "wycliffe": "Which seidist in thin herte, Y schal stie in to heuene, Y schal enhaunse my seete aboue the staris of heuene; Y schal sitte in the hil of testament, in the sidis of the north.", "rotherham": "Yet, thou, didst say in thy heart—The heavens, will I ascend, Above the stars of GOD, will I lift up my throne,—That I may sit in the Mount of Assembly In the Recesses of the North:", "darby": "And thou that didst say in thy heart, I will ascend into the heavens, I will exalt my throne above the stars ofGod, and I will sit upon the mount of assembly, in the recesses of the north;", "twenty": "", "jps": "And thou saidst in thy heart: 'I will ascend into heaven, above the stars of G-d will I exalt my throne, and I will sit upon the mount of meeting, in the uttermost parts of the north;", "acv": "And thou said in thy heart, I will ascend into heaven. I will exalt my throne above the stars of God, and I will sit upon the mount of congregation, in the outermost parts of the north.", "anderson": "", "haweis": "", "noyes": "Thou saidst in thy heart, ‘I will ascend to heaven, Above the stars of God will I exalt my throne; I will sit upon the mount of assembly in the recesses of the north.", "webster": "For thou hast said in thy heart, I will ascend into heaven, I will exalt my throne above the stars of God: I will sit also upon the mount of the congregation, in the sides of the north:", "vulgate": "qui dicebas in corde tuo in caelum conscendam super astra Dei exaltabo solium meum sedebo in monte testamenti in lateribus aquilonis;", "brenton": "But thou saidst in thine heart, I will go up to heaven, I will set my throne above the stars of heaven: I will sit on a lofty mount, on the lofty mountains toward the north:"}}, {"v": 14, "ref": "14:14", "o": "אֶעֱלֶ֖ה עַל בָּ֣מֳתֵי עָ֑ב אֶדַּמֶּ֖ה לְ/עֶלְיֽוֹן", "en": {"kjv": "I will ascend above the heights of the clouds; I will be like the most High.", "web": "I will ascend above the heights of the clouds! I will make myself like the Most High!”", "bsb": "I will ascend above the tops of the clouds; I will make myself like the Most High.”", "asv": "I will ascend above the heights of the clouds; I will make myself like the Most High.", "ylt": "I go up above the heights of a thick cloud, I am like to the Most High.", "dra": "I will ascend above the height of the clouds, I will be like the most High.", "bbe": "I will go higher than the clouds; I will be like the Most High.", "geneva": "I wil ascend aboue ye height of the cloudes, and I will be like the most high.", "wycliffe": "Y schal stie on the hiynesse of cloudis; Y schal be lijk the hiyeste.", "rotherham": "I will mount on the hills of the clouds, I will match the Most High!", "darby": "I will ascend above the heights of the clouds, I will be like the Most High:", "twenty": "", "jps": "I will ascend above the heights of the clouds; I will be like the Most High.'", "acv": "I will ascend above the heights of the clouds. I will make myself like the Most High.", "anderson": "", "haweis": "", "noyes": "I will ascend above the height of the clouds; I will be like the Most High.’", "webster": "I will ascend above the hights of the clouds; I will be like the Most High.", "vulgate": "ascendam super altitudinem nubium ero similis Altissimo;", "brenton": "I will go up above the clouds: I will be like the Most High."}}, {"v": 15, "ref": "14:15", "o": "אַ֧ךְ אֶל שְׁא֛וֹל תּוּרָ֖ד אֶל יַרְכְּתֵי בֽוֹר", "en": {"kjv": "Yet thou shalt be brought down to hell, to the sides of the pit.", "web": "Yet you shall be brought down to Sheol, to the depths of the pit.", "bsb": "But you will be brought down to Sheol, to the lowest depths of the Pit.", "asv": "Yet thou shalt be brought down to Sheol, to the uttermost parts of the pit.", "ylt": "Only--unto Sheol thou art brought down, Unto the sides of the pit.", "dra": "But yet thou shalt be brought down to hell, into the depth of the pit.", "bbe": "But you will come down to the underworld, even to its inmost parts.", "geneva": "But thou shalt bee brought downe to the graue, to the sides of the pit.", "wycliffe": "Netheles thou schalt be drawun doun to helle, in to the depthe of the lake.", "rotherham": "Howbeit, to Hades, shalt thou be brought down,—To the Recesses of the Pit!", "darby": "none the less art thou brought down to Sheol, to the recesses of the pit.", "twenty": "", "jps": "Yet thou shalt be brought down to the nether-world, to the uttermost parts of the pit.", "acv": "Yet thou shall be brought down to Sheol, to the utmost parts of the pit.", "anderson": "", "haweis": "", "noyes": "But thou art brought down to the grave, To the depths of the pit.", "webster": "Yet thou shalt be brought down to hell, to the sides of the pit.", "vulgate": "verumtamen ad infernum detraheris in profundum laci;", "brenton": "But now thou shalt go down to hell, even to the foundations of the earth."}}, {"v": 16, "ref": "14:16", "o": "רֹאֶ֨י/ךָ֙ אֵלֶ֣י/ךָ יַשְׁגִּ֔יחוּ אֵלֶ֖י/ךָ יִתְבּוֹנָ֑נוּ הֲ/זֶ֤ה הָ/אִישׁ֙ מַרְגִּ֣יז הָ/אָ֔רֶץ מַרְעִ֖ישׁ מַמְלָכֽוֹת", "en": {"kjv": "They that see thee shall narrowly look upon thee, and consider thee, saying, Is this the man that made the earth to tremble, that did shake kingdoms;", "web": "Those who see you will stare at you. They will ponder you, saying, “Is this the man who made the earth to tremble, who shook kingdoms;", "bsb": "Those who see you will stare; they will ponder your fate: “Is this the man who shook the earth and made the kingdoms tremble,", "asv": "They that see thee shall gaze at thee, they shall consider thee, saying, Is this the man that made the earth to tremble, that did shake kingdoms;", "ylt": "Thy beholders look to thee, to thee they attend, Is this the man causing the earth to tremble, Shaking kingdoms?", "dra": "They that shall see thee, shall turn toward thee, and behold thee. Is this the man that troubled the earth, that shook kingdoms,", "bbe": "Those who see you will be looking on you with care, they will be in deep thought, saying, Is this the troubler of the earth, the shaker of kingdoms?", "geneva": "They that see thee, shall looke vpon thee and consider thee, saying, Is this the man that made the earth to tremble, and that did shake the kingdomes?", "wycliffe": "Thei that schulen se thee, schulen be bowid doun to thee, and schulen biholde thee. Whether this is the man, that disturblid erthe, that schook togidere rewmes?", "rotherham": "They who see thee, upon thee, will gaze, Upon thee, will thoughtfully muse,—Is this the man who startled the earth? Who terrified kingdoms?", "darby": "They that see thee shall narrowly look upon thee; they shall consider thee, [saying,] Is this the man that made the earth to tremble, that shook kingdoms;", "twenty": "", "jps": "They that saw thee do narrowly look upon thee, they gaze earnestly at thee: 'Is this the man that made the earth to tremble, that did shake kingdoms;", "acv": "Those who see thee shall gaze at thee. They shall consider thee, saying, Is this the man who made the earth to tremble, who shook kingdoms,", "anderson": "", "haweis": "", "noyes": "They that see thee gaze upon thee, and view thee attentively, (and say,) ‘Is this the man that made the earth tremble, That shook kingdoms,", "webster": "They that see thee shall narrowly look upon thee, [and] consider thee, [saying], [Is] this the man that made the earth to tremble, that shook kingdoms:", "vulgate": "qui te viderint ad te inclinabuntur teque prospicient numquid iste est vir qui conturbavit terram qui concussit regna;", "brenton": "They that see thee shall wonder at thee, and say, This is the man that troubled the earth, that made kings to shake;"}}, {"v": 17, "ref": "14:17", "o": "שָׂ֥ם תֵּבֵ֛ל כַּ/מִּדְבָּ֖ר וְ/עָרָ֣י/ו הָרָ֑ס אֲסִירָ֖י/ו לֹא פָ֥תַח בָּֽיְתָ/ה", "en": {"kjv": "That made the world as a wilderness, and destroyed the cities thereof; that opened not the house of his prisoners?", "web": "who made the world like a wilderness, and overthrew its cities; who didn’t release his prisoners to their home?”", "bsb": "who turned the world into a desert and destroyed its cities, who refused to let the captives return to their homes?”", "asv": "that made the world as a wilderness, and overthrew the cities thereof; that let not loose his prisoners to their home?", "ylt": "He hath made the world as a wilderness, And his cities he hath broken down, Of his bound ones he opened not the house.", "dra": "That made the world a wilderness, and destroyed the cities thereof, that opened not the prison to his prisoners?", "bbe": "Who made the world a waste, overturning its towns; who did not let his prisoners loose from the prison-house.", "geneva": "He made the worlde as a wildernesse, and destroied the cities thereof, and opened not the house of his prisoners.", "wycliffe": "that settide the world desert, and distried the citees therof, and openyde not the prisoun to the boundun men of hym?", "rotherham": "Who made the world like a desert? And its cities, brake down? Its prisoners, he loosed not, Each one to his home?", "darby": "[that] made the world as a wilderness, and overthrew the cities thereof; [that] dismissed not his prisoners homewards?", "twenty": "", "jps": "That made the world as a wilderness, and destroyed the cities thereof; that opened not the house of his prisoners?'", "acv": "who made the world as a wilderness, and overthrew the cities of it, who did not let loose his prisoners to their home?", "anderson": "", "haweis": "", "noyes": "That made the world a wilderness, And laid waste its cities, And sent not his captives to their homes?’", "webster": "[That] made the world as a wilderness, and destroyed its cities; [that] opened not the house of his prisoners?", "vulgate": "qui posuit orbem desertum et urbes eius destruxit vinctis eius non aperuit carcerem;", "brenton": "that made the whole world desolate, and destroyed its cities; he loosed not those who were in captivity."}}, {"v": 18, "ref": "14:18", "o": "כָּל מַלְכֵ֥י גוֹיִ֖ם כֻּלָּ֑/ם שָׁכְב֥וּ בְ/כָב֖וֹד אִ֥ישׁ בְּ/בֵיתֽ/וֹ", "en": {"kjv": "All the kings of the nations, even all of them, lie in glory, every one in his own house.", "web": "All the kings of the nations, sleep in glory, everyone in his own house.", "bsb": "All the kings of the nations lie in state, each in his own tomb.", "asv": "All the kings of the nations, all of them, sleep in glory, every one in his own house.", "ylt": "All kings of nations--all of them, Have lain down in honour, each in his house,", "dra": "All the kings of the nations have all of them slept in glory, every one in his own house.", "bbe": "All the kings of the earth are at rest in glory, every man in his house,", "geneva": "All the Kings of the nations, euen they all sleepe in glorie, euery one in his owne house.", "wycliffe": "Alle the kyngis of hethene men, alle slepten in glorie, a man in his hous.", "rotherham": "All the kings of the nations—they all, are lying in state Each one in his crypt;", "darby": "— All the kings of the nations, all of them, lie in glory, every one in his own house;", "twenty": "", "jps": "All the kings of the nations, all of them, sleep in glory, every one in his own house.", "acv": "All the kings of the nations, all of them, sleep in glory, each one in his own house.", "anderson": "", "haweis": "", "noyes": "All the kings of the nations, yea, all of them, Lie down in glory, each in his own sepulchre;", "webster": "All the kings of the nations, [even] all of them, lie in glory, every one in his own house.", "vulgate": "omnes reges gentium universi dormierunt in gloria vir in domo sua;", "brenton": "All the kings of the nations lie in honour, every man in his house."}}, {"v": 19, "ref": "14:19", "o": "וְ/אַתָּ֞ה הָשְׁלַ֤כְתָּ מִֽ/קִּבְרְ/ךָ֙ כְּ/נֵ֣צֶר נִתְעָ֔ב לְב֥וּשׁ הֲרֻגִ֖ים מְטֹ֣עֲנֵי חָ֑רֶב יוֹרְדֵ֥י אֶל אַבְנֵי ב֖וֹר כְּ/פֶ֥גֶר מוּבָֽס", "en": {"kjv": "But thou art cast out of thy grave like an abominable branch, and as the raiment of those that are slain, thrust through with a sword, that go down to the stones of the pit; as a carcase trodden under feet.", "web": "But you are cast away from your tomb like an abominable branch, clothed with the slain, who are thrust through with the sword, who go down to the stones of the pit; like a dead body trodden under foot.", "bsb": "But you are cast out of your grave like a rejected branch, covered by those slain with the sword, and dumped into a rocky pit like a carcass trampled underfoot.", "asv": "But thou art cast forth away from thy sepulchre like an abominable branch, clothed with the slain, that are thrust through with the sword, that go down to the stones of the pit; as a dead body trodden under foot.", "ylt": "And--thou hast been cast out of thy grave, As an abominable branch, raiment of the slain, Thrust through ones of the sword, Going down unto the sons of the pit, As a carcase trodden down.", "dra": "But thou art cast out of thy grave, as an unprofitable branch defiled, and wrapped up among them that were slain by the sword, and art gone down to the bottom of the pit, as a rotten carcass.", "bbe": "But you, like a birth before its time, are stretched out with no resting-place in the earth; clothed with the bodies of the dead who have been put to the sword, who go down to the lowest parts of the underworld; a dead body, crushed under foot.", "geneva": "But thou art cast out of thy graue like an abominable branch: like the raiment of those that are slaine, and thrust thorowe with a sword, which goe downe to the stones of the pit, as a carkeise troden vnder feete.", "wycliffe": "But thou art cast out of thi sepulcre, as an vnprofitable stok, as defoulid with rot; and wlappid with hem that ben slayn with swerd, and yeden doun to the foundement of the lake.", "rotherham": "But, thou, art flung out from thy grave, Like a scion detested, Beshrouded with slain, the pierced of the sword, Like a carcase trod underfoot:", "darby": "but thou art cast out of thy grave like an abominable branch, covered with the slain — those thrust through with the sword, that go down to the stones of the pit: like a carcase trodden under foot.", "twenty": "", "jps": "But thou art cast forth away from thy grave like an abhorred offshoot, in the raiment of the slain, that are thrust through with the sword, that go down to the pavement of the pit, as a carcass trodden under foot.", "acv": "But thou are cast forth away from thy sepulcher like an abominable branch, clothed with the slain, who are thrust through with the sword, who go down to the stones of the pit, as a dead body trodden under foot.", "anderson": "", "haweis": "", "noyes": "But thou art cast forth without a grave, Like a worthless branch; Covered with the slain, who are pierced by the sword, Who go down to the stones of the pit, Like a carcass trampled under foot.", "webster": "But thou art cast out of thy grave like an abominable branch, [and as] the raiment of those that are slain, thrust through with a sword, that go down to the stones of the pit; as a carcass trodden under feet.", "vulgate": "tu autem proiectus es de sepulchro tuo quasi stirps inutilis pollutus et obvolutus qui interfecti sunt gladio et descenderunt ad fundamenta laci quasi cadaver putridum;", "brenton": "But thou shalt be cast forth on the mountains, as a loathed carcase, with many dead who have been pierced with swords, going down to the grave."}}, {"v": 20, "ref": "14:20", "o": "לֹֽא תֵחַ֤ד אִתָּ/ם֙ בִּ/קְבוּרָ֔ה כִּֽי אַרְצְ/ךָ֥ שִׁחַ֖תָּ עַמְּ/ךָ֣ הָרָ֑גְתָּ לֹֽא יִקָּרֵ֥א לְ/עוֹלָ֖ם זֶ֥רַע מְרֵעִֽים", "en": {"kjv": "Thou shalt not be joined with them in burial, because thou hast destroyed thy land, and slain thy people: the seed of evildoers shall never be renowned.", "web": "You will not join them in burial, because you have destroyed your land. You have killed your people. The seed of evildoers will not be named forever.", "bsb": "You will not join them in burial, since you have destroyed your land and slaughtered your own people. The offspring of the wicked will never again be mentioned.", "asv": "Thou shalt not be joined with them in burial, because thou hast destroyed thy land, thou hast slain thy people; the seed of evil-doers shall not be named for ever.", "ylt": "Thou art not united with them in burial, For thy land thou hast destroyed, Thy people thou hast slain, Not named to the age is the seed of evil doers.", "dra": "Thou shalt not keep company with them, even in burial: for thou hast destroyed thy land, thou hast slain thy people: the seed of the wicked shall not be named for ever.", "bbe": "As for your fathers, you will not be united with them in their resting-place, because you have been the cause of destruction to your land, and of death to your people; the seed of the evil-doer will have no place in the memory of man.", "geneva": "Thou shalt not be ioyned with them in the graue, because thou hast destroied thine owne lande, and slaine thy people: the seede of the wicked shall not be renoumed for euer.", "wycliffe": "As a rotun careyn, thou schalt not haue felouschipe, nethir with hem in sepulture, for thou hast lost thi lond, thou hast slayn the puple; the seed of the worst men schal not be clepid with outen ende.", "rotherham": "As for them who go down to the stones of the Pit, Thou shalt not be united with them in burial; For thy land, thou didst ruin Thy people, didst slay,—Unnamed to times age-abiding, Be the seed of the wicked!", "darby": "Thou shalt not be joined with them in burial; for thou hast destroyed thy land, hast slain thy people. Of the seed of evildoers no mention shall be made for ever.", "twenty": "", "jps": "Thou shalt not be joined with them in burial, because thou hast destroyed thy land, thou hast slain thy people; the seed of evil-doers shall not be named for ever.", "acv": "Thou shall not be joined with them in burial, because thou have destroyed thy land. Thou have slain thy people. The seed of evildoers shall not be named forever.", "anderson": "", "haweis": "", "noyes": "Thou shalt not be joined with them in the grave, Because thou hast destroyed thy country, And slain thy people; The race of evil-doers shall nevermore be named.", "webster": "Thou shalt not be joined with them in burial, because thou hast destroyed thy land, [and] slain thy people: the seed of evil-doers shall never be renowned.", "vulgate": "non habebis consortium neque cum eis in sepultura tu enim terram disperdisti tu populum occidisti non vocabitur in aeternum semen pessimorum;", "brenton": "As a garment defiled with blood shall not be pure, so neither shalt thou be pure; because thou hast destroyed my land, and hast slain my people: thou shalt not endure for ever, —thou an evil seed."}}, {"v": 21, "ref": "14:21", "o": "הָכִ֧ינוּ לְ/בָנָ֛י/ו מַטְבֵּ֖חַ בַּ/עֲוֺ֣ן אֲבוֹתָ֑/ם בַּל יָקֻ֨מוּ֙ וְ/יָ֣רְשׁוּ אָ֔רֶץ וּ/מָלְא֥וּ פְנֵֽי תֵבֵ֖ל עָרִֽים", "en": {"kjv": "Prepare slaughter for his children for the iniquity of their fathers; that they do not rise, nor possess the land, nor fill the face of the world with cities.", "web": "Prepare for slaughter of his children because of the iniquity of their fathers, that they not rise up and possess the earth, and fill the surface of the world with cities.", "bsb": "Prepare a place to slaughter his sons for the iniquities of their forefathers. They will never rise up to possess a land or cover the earth with their cities.", "asv": "Prepare ye slaughter for his children for the iniquity of their fathers, that they rise not up, and possess the earth, and fill the face of the world with cities.", "ylt": "Prepare ye for his sons slaughter; Because of the iniquity of their fathers, They rise not, nor have possessed the land, Nor filled the face of the world with cities.", "dra": "Prepare his children for slaughter for the iniquity of their fathers: they shall not rise up, nor inherit the land, nor fill the face of the world with cities.", "bbe": "Make ready a place of death for his children, because of the evil-doing of their father; so that they may not come up and take the earth for their heritage, covering the face of the world with waste places.", "geneva": "Prepare a slaughter for his children, for the iniquitie of their fathers: let them not rise vp nor possesse the land, nor fil the face of the world with enemies.", "wycliffe": "Make ye redi hise sones to sleying, for the wickidnesse of her fadris; thei schulen not rise, nether thei schulen enherite the lond, nether thei schulen fille the face of the roundenesse of citees.", "rotherham": "Prepare—for his sons—shambles. For the iniquity of their fathers,—They shall not rise nor possess the earth, Nor fill the face of the world with cities.", "darby": "Prepare ye slaughter for his children, because of the iniquity of their fathers; that they may not rise up and possess the earth, nor fill the face of the world with cities.", "twenty": "", "jps": "Prepare ye slaughter for his children for the iniquity of their fathers; that they rise not up, and possess the earth, and fill the face of the world with cities.", "acv": "Prepare ye slaughter for his sons for the iniquity of their fathers, that they not rise up, and possess the earth, and fill the face of the world with cities.", "anderson": "", "haweis": "", "noyes": "Prepare ye slaughter for his children, For the iniquity of their fathers, That they may no more arise, and possess the earth, And fill the world with enemies!\"", "webster": "Prepare slaughter for his children for the iniquity of their fathers; that they may not rise, nor possess the land, nor fill the face of the world with cities.", "vulgate": "praeparate filios eius occisioni in iniquitate patrum eorum non consurgent nec hereditabunt terram neque implebunt faciem orbis civitatum;", "brenton": "Prepare thy children to be slain for the sins of their father; that they arise not, and inherit the earth, nor fill the earth with wars."}}, {"v": 22, "ref": "14:22", "o": "וְ/קַמְתִּ֣י עֲלֵי/הֶ֔ם נְאֻ֖ם יְהוָ֣ה צְבָא֑וֹת וְ/הִכְרַתִּ֨י לְ/בָבֶ֜ל שֵׁ֥ם וּ/שְׁאָ֛ר וְ/נִ֥ין וָ/נֶ֖כֶד נְאֻם יְהוָֽה", "en": {"kjv": "For I will rise up against them, saith the Lord of hosts, and cut off from Babylon the name, and remnant, and son, and nephew, saith the Lord.", "web": "“I will rise up against them,” says Yahweh of Armies, “and cut off from Babylon name and remnant, and son and son’s son,” says Yahweh.", "bsb": "“I will rise up against them,” declares the LORD of Hosts. “I will cut off from Babylon her name and her remnant, her offspring and her posterity,” declares the LORD.", "asv": "And I will rise up against them, saith Jehovah of hosts, and cut off from Babylon name and remnant, and son and son’s son, saith Jehovah.", "ylt": "And I have risen up against them, (The affirmation of Jehovah of Hosts,) And have cut off, in reference to Babylon, Name and remnant, and continuator and successor, The affirmation of Jehovah.", "dra": "And I will rise up against them, saith the Lord of hosts: and I will destroy the name of Babylon, and the remains, and the bud, and the offspring, saith the Lord.", "bbe": "For I will come up against them, says the Lord of armies, cutting off from Babylon name and offspring, son and son's son, says the Lord.", "geneva": "For I wil rise vp against them (sayth the Lord of hostes) and will cut off from Babel the name and the remnant and the sonne, and the nephew, sayth the Lord:", "wycliffe": "And Y schal rise on hem, seith the Lord of oostis, and Y schal leese the name of Babyloyne, and the relifs, and generacioun, and seed, seith the Lord.", "rotherham": "I will rise. Then. against them, Declareth Yahweh of hosts,—And will cut off from Babylon Record and remnant And scion and seed, Declareth Yahweh.", "darby": "For I will rise up against them, saith Jehovah of hosts, and cut off from Babylon name and remnant, and scion and descendant, saith Jehovah.", "twenty": "", "jps": "And I will rise up against them, saith HaShem of hosts, and cut off from Babylon name and remnant, and offshoot and offspring, saith HaShem.", "acv": "And I will rise up against them, says Jehovah of hosts, and cut off from Babylon name and remnant, and son and son's son, says Jehovah.", "anderson": "", "haweis": "", "noyes": "For I will arise against them, saith Jehovah of hosts, And I will cut off from Babylon the name and remnant, Posterity and offspring, saith Jehovah.", "webster": "For I will arise against them, saith the LORD of hosts, and cut off from Babylon the name, and remnant, and son, and nephew, saith the LORD.", "vulgate": "et consurgam super eos dicit Dominus exercituum et perdam Babylonis nomen et reliquias et germen et progeniem ait Dominus;", "brenton": "And I will rise up against them, saith the Lord of hosts, and I will destroy their name, and remnant, and seed: thus saith the Lord."}}, {"v": 23, "ref": "14:23", "o": "וְ/שַׂמְתִּ֛י/הָ לְ/מוֹרַ֥שׁ קִפֹּ֖ד וְ/אַגְמֵי מָ֑יִם וְ/טֵֽאטֵאתִ֨י/הָ֙ בְּ/מַטְאֲטֵ֣א הַשְׁמֵ֔ד נְאֻ֖ם יְהוָ֥ה צְבָאֽוֹת", "en": {"kjv": "I will also make it a possession for the bittern, and pools of water: and I will sweep it with the besom of destruction, saith the Lord of hosts.", "web": "“I will also make it a possession for the porcupine, and pools of water. I will sweep it with the broom of destruction,” says Yahweh of Armies.", "bsb": "“I will make her a place for owls and for swamplands; I will sweep her away with the broom of destruction,” declares the LORD of Hosts.", "asv": "I will also make it a possession for the porcupine, and pools of water: and I will sweep it with the besom of destruction, saith Jehovah of hosts.", "ylt": "And have made it for a possession of a bittern, And ponds of waters, And daubed it with the mire of destruction, The affirmation of Jehovah of Hosts!", "dra": "And I will make it a possession for the ericius and pools of waters, and I will sweep it and wear it out with a besom, saith the Lord of hosts.", "bbe": "And I will make you a heritage for the hedgehog, and pools of water: and I will go through it with the brush of destruction, says the Lord of armies.", "geneva": "And I wil make it a possession to ye hedgehogge, and pooles of water, and I will sweepe it with the besome of destruction, sayeth the Lord of hostes.", "wycliffe": "And Y schal sette that Babiloyne in to possessioun of an irchoun, and in to mareisis of watris; and Y schal swepe it with a beesme, and Y schal stampe, seith the Lord of oostis.", "rotherham": "And will make her a possession for the bittern, And marshes of water,—And will sweep it with the besom of destruction, Declareth Yahweh of hosts.", "darby": "And I will make it a possession for the bittern, and pools of water; and I will sweep it with the besom of destruction, saith Jehovah of hosts.", "twenty": "", "jps": "I will also make it a possession for the bittern, and pools of water; and I will sweep it with the besom of destruction, saith HaShem of hosts.", "acv": "I will also make it a possession for the porcupine, and pools of water. And I will sweep it with the broom of destruction, says Jehovah of hosts.", "anderson": "", "haweis": "", "noyes": "I will make her the possession of the porcupine, and pools of water; Yea, I will sweep her away with the besom of destruction, saith Jehovah of hosts.", "webster": "I will also make it a possession for the bittern, and pools of water: and I will sweep it with the besom of destruction, saith the LORD of hosts.", "vulgate": "et ponam eam in possessionem ericii et in paludes aquarum et scopabo eam in scopa terens dicit Dominus exercituum;", "brenton": "And I will make the region of Babylon desert, so that hedgehogs shall dwell there, and it shall come to nothing: and I will make it a pit of clay for destruction."}}, {"v": 24, "ref": "14:24", "o": "נִשְׁבַּ֛ע יְהוָ֥ה צְבָא֖וֹת לֵ/אמֹ֑ר אִם לֹ֞א כַּ/אֲשֶׁ֤ר דִּמִּ֨יתִי֙ כֵּ֣ן הָיָ֔תָה וְ/כַ/אֲשֶׁ֥ר יָעַ֖צְתִּי הִ֥יא תָקֽוּם", "en": {"kjv": "The Lord of hosts hath sworn, saying, Surely as I have thought, so shall it come to pass; and as I have purposed, so shall it stand:", "web": "Yahweh of Armies has sworn, saying, “Surely, as I have thought, so shall it happen; and as I have purposed, so shall it stand:", "bsb": "The LORD of Hosts has sworn: “Surely, as I have planned, so will it be; as I have purposed, so will it stand.", "asv": "Jehovah of hosts hath sworn, saying, Surely, as I have thought, so shall it come to pass; and as I have purposed, so shall it stand:", "ylt": "Sworn hath Jehovah of Hosts, saying, `As I thought--so hath it not been? And as I counselled--it standeth;", "dra": "The Lord of hosts hath sworn, saying: Surely as I have thought, so shall it be: and as I have purposed,", "bbe": "The Lord has taken an oath, saying, My design will certainly come about, and my purpose will be effected:", "geneva": "The Lord of hostes hath sworne, saying, Surely like as I haue purposed, so shall it come to passe, and as I haue consulted, it shall stand:", "wycliffe": "The Lord of oostis swoor, seiynge, Whether it schal not be so, as Y gesside, and it schal bifalle so, as Y tretide in soule?", "rotherham": "Yahweh of hosts, hath sworn, saying,—Surely as I intended, so, hath it come to pass, And as I purposed, the same, shall stand:—", "darby": "Jehovah of hosts hath sworn saying, Assuredly as I have thought, so shall it come to pass; and as I have purposed, it shall stand:", "twenty": "", "jps": "HaShem of hosts hath sworn, saying: Surely as I have thought, so shall it come to pass; and as I have purposed, so shall it stand,", "acv": "Jehovah of hosts has sworn, saying, Surely, as I have thought, so shall it come to pass, and as I have purposed, so shall it stand,", "anderson": "", "haweis": "", "noyes": "Jehovah of hosts hath sworn, saying, Surely, as I have devised, so shall it come to pass, The purpose which I have formed, that shall stand,", "webster": "The LORD of hosts hath sworn, saying, Surely as I have thought, so shall it come to pass; and as I have purposed, [so] shall it stand.", "vulgate": "iuravit Dominus exercituum dicens si non ut putavi ita erit et quomodo mente tractavi;", "brenton": "Thus saith the Lord of hosts, As I have said, so it shall be: and as I have purposed, so the matter shall remain:"}}, {"v": 25, "ref": "14:25", "o": "לִ/שְׁבֹּ֤ר אַשּׁוּר֙ בְּ/אַרְצִ֔/י וְ/עַל הָרַ֖/י אֲבוּסֶ֑/נּוּ וְ/סָ֤ר מֵֽ/עֲלֵי/הֶם֙ עֻלּ֔/וֹ וְ/סֻ֨בֳּל֔/וֹ מֵ/עַ֥ל שִׁכְמ֖/וֹ יָסֽוּר", "en": {"kjv": "That I will break the Assyrian in my land, and upon my mountains tread him under foot: then shall his yoke depart from off them, and his burden depart from off their shoulders.", "web": "that I will break the Assyrian in my land, and tread him under foot on my mountains. Then his yoke will leave them, and his burden leave their shoulders.", "bsb": "I will break Assyria in My land; I will trample him on My mountain. His yoke will be taken off My people, and his burden removed from their shoulders.”", "asv": "that I will break the Assyrian in my land, and upon my mountains tread him under foot: then shall his yoke depart from off them, and his burden depart from off their shoulder.", "ylt": "To break Asshur in My land, And on My mountains I tread him down, And turned from off them hath his yoke, Yea, his burden from off their shoulder turneth aside.", "dra": "So shall it fall out: That I will destroy the Assyrian in my land, and upon my mountains tread him under foot: and his yoke shall be taken away from them, and his burden shall be taken off their shoulder.", "bbe": "To let the Assyrian be broken in my land, and crushed under foot on my mountains: there will his yoke be taken away from them, and his rule over them come to an end.", "geneva": "That I will breake to pieces Asshur in my land, and vpon my mountaines will I treade him vnder foote: so that his yoke shall depart from them, and his burden shall be taken from off their shoulder.", "wycliffe": "That Y al to-breke the kyng of Assiriens in my lond, and that Y defoule hym in myn hillis; and his yok schal be takun awei fro hem, and his birthun schal be takun awei fro the schuldur of hem.", "rotherham": "That I will break in pieces the Assyrian in my land, Yea upon my mountains, will I tread him underfoot,—So shall be removed from off them his yoke, And his burden, from off their shoulder shall be removed.", "darby": "to break the Assyrian in my land; and upon my mountains will I tread him under foot; and his yoke shall depart from off them, and his burden depart from off their shoulders.", "twenty": "", "jps": "That I will break Asshur in My land, and upon My mountains tread him under foot; then shall his yoke depart from off them, and his burden depart from off their shoulder.", "acv": "that I will break the Assyrian in my land, and tread him under foot upon my mountains. Then shall his yoke depart from off them, and his burden depart from off their shoulder.", "anderson": "", "haweis": "", "noyes": "To crush the Assyrian in my land, And to trample him on my mountains. Then shall his yoke depart from them, And his burden be removed from their shoulders.", "webster": "That I will break the Assyrian in my land, and upon my mountains tread him under foot: then shall his yoke depart from off them, and his burden depart from off their shoulders.", "vulgate": "sic eveniet ut conteram Assyrium in terra mea et in montibus meis conculcem eum et auferetur ab eis iugum eius et onus illius ab umero eorum tolletur;", "brenton": "even to destroy the Assyrians upon my land, and upon my mountains: and they shall be for trampling; and their yoke shall be taken away from them, and their glory shall be taken away from their shoulders."}}, {"v": 26, "ref": "14:26", "o": "זֹ֛את הָ/עֵצָ֥ה הַ/יְּעוּצָ֖ה עַל כָּל הָ/אָ֑רֶץ וְ/זֹ֛את הַ/יָּ֥ד הַ/נְּטוּיָ֖ה עַל כָּל הַ/גּוֹיִֽם", "en": {"kjv": "This is the purpose that is purposed upon the whole earth: and this is the hand that is stretched out upon all the nations.", "web": "This is the plan that is determined for the whole earth. This is the hand that is stretched out over all the nations.", "bsb": "This is the plan devised for the whole earth, and this is the hand stretched out over all the nations.", "asv": "This is the purpose that is purposed upon the whole earth; and this is the hand that is stretched out upon all the nations.", "ylt": "This is the counsel that is counselled for all the earth, And this is the hand that is stretched out for all the nations.", "dra": "This is the counsel, that I have purposed upon all the earth, and this is the hand that is stretched out upon all nations.", "bbe": "This is the purpose for all the earth: and this is the hand stretched out over all nations.", "geneva": "This is the counsell that is consulted vpon the whole worlde, and this is the hande stretched out ouer all the nations,", "wycliffe": "This is the councel which Y thouyte on al the lond, and this is the hond stretchid forth on alle folkis.", "rotherham": "This, is the purpose that is purposed upon all the earth,—And, this, the hand outstretched over all the nations;", "darby": "This is the counsel which is purposed concerning the whole earth; and this is the hand which is stretched out upon all the nations.", "twenty": "", "jps": "This is the purpose that is purposed upon the whole earth; and this is the hand that is stretched out upon all the nations.", "acv": "This is the purpose that is purposed upon the whole earth, and this is the hand that is stretched out upon all the nations.", "anderson": "", "haweis": "", "noyes": "This is the purpose which is formed concerning all the earth, And this the hand which is stretched out over all the nations.", "webster": "This [is] the purpose that is purposed upon the whole earth: and this [is] the hand that is stretched over all the nations.", "vulgate": "hoc consilium quod cogitavi super omnem terram et haec est manus extenta super universas gentes;", "brenton": "This is the purpose which the Lord has purposed upon the whole earth: and this the hand that is uplifted against all the nations."}}, {"v": 27, "ref": "14:27", "o": "כִּֽי יְהוָ֧ה צְבָא֛וֹת יָעָ֖ץ וּ/מִ֣י יָפֵ֑ר וְ/יָד֥/וֹ הַ/נְּטוּיָ֖ה וּֽ/מִ֥י יְשִׁיבֶֽ/נָּה", "en": {"kjv": "For the Lord of hosts hath purposed, and who shall disannul it? and his hand is stretched out, and who shall turn it back?", "web": "For Yahweh of Armies has planned, and who can stop it? His hand is stretched out, and who can turn it back?”", "bsb": "The LORD of Hosts has purposed, and who can thwart Him? His hand is outstretched, so who can turn it back?", "asv": "For Jehovah of hosts hath purposed, and who shall annul it? and his hand is stretched out, and who shall turn it back?", "ylt": "For Jehovah of Hosts hath purposed, And who doth make void? And His hand that is stretched out, Who doth turn it back?'", "dra": "For the Lord of hosts hath decreed, and who can disannul it? and his hand is stretched out: and who shall turn it away?", "bbe": "For it is the purpose of the Lord of armies, and who will make it of no effect? when his hand is stretched out, by whom may it be turned back?", "geneva": "Because the Lord of hostes hath determined it, and who shall disanull it? and his hande is stretched out, and who shall turne it away?", "wycliffe": "For whi the Lord of oostis hath demed, and who mai make vnstidfaste? and his hond is stretchid forth, and who schal turne it awei?", "rotherham": "For, Yahweh of hosts, hath purposed,—And who shall frustrate? And, his, is the hand outstretched, And who shall turn it back?", "darby": "For Jehovah of hosts hath purposed, and who shall frustrate [it]? And his hand is stretched out, and who shall turn it back?", "twenty": "", "jps": "For HaShem of hosts hath purposed, and who shall disannul it? And His hand is stretched out, and who shall turn it back?", "acv": "For Jehovah of hosts has purposed, and who shall annul it? And his hand is stretched out, and who shall turn it back?", "anderson": "", "haweis": "", "noyes": "For Jehovah of hosts hath decreed, and who shall disannul it? And his hand is stretched out, and who shall turn it back?", "webster": "For the LORD of hosts hath purposed, and who shall disannul [it]? and his hand [is] stretched out, and who shall turn it back?", "vulgate": "Dominus enim exercituum decrevit et quis poterit infirmare et manus eius extenta et quis avertet eam;", "brenton": "For what the Holy God has purposed, who shall frustrate? and who shall turn back his uplifted hand?"}}, {"v": 28, "ref": "14:28", "o": "בִּ/שְׁנַת מ֖וֹת הַ/מֶּ֣לֶךְ אָחָ֑ז הָיָ֖ה הַ/מַּשָּׂ֥א הַ/זֶּֽה", "en": {"kjv": "In the year that king Ahaz died was this burden.", "web": "This burden was in the year that king Ahaz died.", "bsb": "In the year that King Ahaz died, this burden was received:", "asv": "In the year that king Ahaz died was this burden.", "ylt": "In the year of the death of king Ahaz was this burden:", "dra": "In the year that king Achaz died, was this burden:", "bbe": "In the year of the death of King Ahaz this word came to the prophet:", "geneva": "In the yeere that King Ahaz died, was this burden.", "wycliffe": "The birthun of Filisteis. In the yeer wheryne kyng Achas diede, this birthun was maad.", "rotherham": "In the year that King Ahaz died, came this oracle:—", "darby": "In the year of the death of king Ahaz was this burden:", "twenty": "", "jps": "In the year that king Ahaz died was this burden.", "acv": "In the year that king Ahaz died was this burden.", "anderson": "", "haweis": "", "noyes": "In the year in which Ahaz the king died came this prophecy.", "webster": "In the year that king Ahaz died was this burden.", "vulgate": "in anno quo mortuus est rex Ahaz factum est onus istud;", "brenton": "In the year in which king Achaz died this word came."}}, {"v": 29, "ref": "14:29", "o": "אַֽל תִּשְׂמְחִ֤י פְלֶ֨שֶׁת֙ כֻּלֵּ֔/ךְ כִּ֥י נִשְׁבַּ֖ר שֵׁ֣בֶט מַכֵּ֑/ךְ כִּֽי מִ/שֹּׁ֤רֶשׁ נָחָשׁ֙ יֵ֣צֵא צֶ֔פַע וּ/פִרְי֖/וֹ שָׂרָ֥ף מְעוֹפֵֽף", "en": {"kjv": "Rejoice not thou, whole Palestina, because the rod of him that smote thee is broken: for out of the serpent’s root shall come forth a cockatrice, and his fruit shall be a fiery flying serpent.", "web": "Don’t rejoice, O Philistia, all of you, because the rod that struck you is broken; for out of the serpent’s root an adder will emerge, and his fruit will be a fiery flying serpent.", "bsb": "Do not rejoice, all you Philistines, that the rod that struck you is broken. For a viper will spring from the root of the snake, and a flying serpent from its egg.", "asv": "Rejoice not, O Philistia, all of thee, because the rod that smote thee is broken; for out of the serpent’s root shall come forth an adder, and his fruit shall be a fiery flying serpent.", "ylt": "Rejoice not thou, Philistia, all of thee, That broken hath been the rod of thy smiter, For from the root of a serpent cometh out a viper, And its fruit is a flying saraph.", "dra": "Rejoice not thou, whole Philistia, that the rod of him that struck thee is broken in pieces: for out of the root of the serpent shall come forth a basilisk, and his seed shall swallow the bird.", "bbe": "Be not glad, O Philistia, all of you, because the rod which was on you is broken: for out of the snake's root will come a poison-snake, and its fruit will be a winged poison-snake.", "geneva": "Reioyce not, (thou whole Palestina) because the rod of him that did beat thee, is broken for out of the serpents roote shall come forth a cockatrise, and the fruit therof shalbe a firy flying serpent.", "wycliffe": "Al thou Filistea, be not glad, for the yerde of thi smytere is maad lesse; for whi a cocatrice schal go out of the roote of an eddre, and his seed schal soupe up a brid.", "rotherham": "Do not rejoice, Philistia, any of thee, In that the rod of him that smote thee, is broken,—For, out of the root of the serpent, shall come forth, a viper, And his fruit be a fiery dragon that flieth.", "darby": "Rejoice not thou, Philistia, all of thee, because the rod that smote thee is broken; for out of the serpent's root shall come forth a viper, and his fruit shall be a fiery flying serpent.", "twenty": "", "jps": "Rejoice not, O Philistia, all of thee, because the rod that smote thee is broken: for out of the serpent's root shall come forth a basilisk, and his fruit shall be a flying serpent.", "acv": "Rejoice not, O Philistia, all of thee, because the rod that smote thee is broken. For out of the serpent's root shall come forth an adder, and his fruit shall be a fiery flying serpent.", "anderson": "", "haweis": "", "noyes": "Rejoice not, all Philistia, Because the rod that smote thee is broken, For from the root of a serpent shall come forth a basilisk, And his fruit shall be a flying, fiery serpent.", "webster": "Rejoice not thou, all Palestina, because the rod of him that smote thee is broken: for out of the serpent's root shall come forth a basilisk, and his fruit [shall be] a fiery flying serpent.", "vulgate": "ne laeteris Philisthea omnis tu quoniam comminuta est virga percussoris tui de radice enim colubri egredietur regulus et semen eius absorbens volucrem;", "brenton": "Rejoice not, all ye Philistines, because the yoke of him that smote you is broken: for out of the seed of the serpent shall come forth the young asps, and their young shall come forth flying serpents,"}}, {"v": 30, "ref": "14:30", "o": "וְ/רָעוּ֙ בְּכוֹרֵ֣י דַלִּ֔ים וְ/אֶבְיוֹנִ֖ים לָ/בֶ֣טַח יִרְבָּ֑צוּ וְ/הֵמַתִּ֤י בָֽ/רָעָב֙ שָׁרְשֵׁ֔/ךְ וּ/שְׁאֵרִיתֵ֖/ךְ יַהֲרֹֽג", "en": {"kjv": "And the firstborn of the poor shall feed, and the needy shall lie down in safety: and I will kill thy root with famine, and he shall slay thy remnant.", "web": "The firstborn of the poor will eat, and the needy will lie down in safety; and I will kill your root with famine, and your remnant will be killed.", "bsb": "Then the firstborn of the poor will find pasture, and the needy will lie down in safety, but I will kill your root by famine, and your remnant will be slain.", "asv": "And the first-born of the poor shall feed, and the needy shall lie down in safety; and I will kill thy root with famine, and thy remnant shall be slain.", "ylt": "And delighted have the first-born of the poor, And the needy in confidence lie down, And I have put to death with famine thy root, And thy remnant it slayeth.", "dra": "And the firstborn of the poor shall be fed, and the poor shall rest with confidence: and I will make thy root perish with famine, and I will kill thy remnant.", "bbe": "And the poorest of the land will have food, and those in need will be given a safe resting-place: but your seed will come to an end for need of food, and the rest of you will be put to the sword.", "geneva": "For the first borne of the poore shall be fed, and the needie shall lie downe in safetie: and I will kill thy roote with famine, and it shall slay thy remnant.", "wycliffe": "And the firste gendrid of pore men schulen be fed, and pore men schulen reste feithfuli; and Y schal make thi throte to perisch in hungur, and Y schal sle thi relifs.", "rotherham": "Then shall feed the firstborn of the poor, And the needy, in confidence lie down,—And I will kill with famine thy root, And thy residue, shall be slain.", "darby": "And the firstborn of the poor shall feed, and the needy shall lie down in safety; but I will kill thy root with famine, and thy remnant shall be slain.", "twenty": "", "jps": "And the first-born of the poor shall feed, and the needy shall lie down in safety; and I will kill thy root with famine, and thy remnant shall be slain.", "acv": "And the firstborn of the poor shall feed, and the needy shall lie down in safety. And I will kill thy root with famine, and thy remnant shall be slain.", "anderson": "", "haweis": "", "noyes": "Then shall the most wretched of the poor feed quietly, And the needy shall lie down in security; For I will kill thy root with famine, And thy remnant shall be slain.", "webster": "And the first-born of the poor shall feed, and the needy shall lie down in safety: and I will kill thy root with famine, and he shall slay thy remnant.", "vulgate": "et pascentur primogeniti pauperum et pauperes fiducialiter requiescent et interire faciam in fame radicem tuam et reliquias tuas interficiam;", "brenton": "And the poor shall be fed by him, and poor men shall rest in peace: but he shall destroy thy seed with hunger, and shall destroy thy remnant."}}, {"v": 31, "ref": "14:31", "o": "הֵילִ֤ילִֽי שַׁ֨עַר֙ זַֽעֲקִי עִ֔יר נָמ֖וֹג פְּלֶ֣שֶׁת כֻּלֵּ֑/ךְ כִּ֤י מִ/צָּפוֹן֙ עָשָׁ֣ן בָּ֔א וְ/אֵ֥ין בּוֹדֵ֖ד בְּ/מוֹעָדָֽי/ו", "en": {"kjv": "Howl, O gate; cry, O city; thou, whole Palestina, art dissolved: for there shall come from the north a smoke, and none shall be alone in his appointed times.", "web": "Howl, gate! Cry, city! You are melted away, Philistia, all of you; for smoke comes out of the north, and there is no straggler in his ranks.", "bsb": "Wail, O gate! Cry out, O city! Melt away, all you Philistines! For a cloud of smoke comes from the north, and there are no stragglers in its ranks.", "asv": "Howl, O gate; cry, O city; thou art melted away, O Philistia, all of thee; for there cometh a smoke out of the north, and there is no straggler in his ranks.", "ylt": "Howl, O gate; cry, O city, Melted art thou, Philistia, all of thee, For from the north smoke hath come, And there is none alone in his set places.", "dra": "Howl, O gate; cry, O city: all Philistia is thrown down: for a smoke shall come from the north, and there is none that shall escape his troop.", "bbe": "Send out a cry, O door! Make sounds of sorrow, O town! All your land has come to nothing, O Philistia; for there comes a smoke out of the north, and everyone keeps his place in the line.", "geneva": "Howle, O gate, crie, O citie: thou whole lande of Palestina art dissolued, for there shall come from the North a smoke, and none shalbe alone, at his time appointed.", "wycliffe": "Yelle, thou yate; cry, thou citee, al Filistea is cast doun; for whi smoke schal come fro the north, and noon is that schal ascape his oost.", "rotherham": "Howl—O gate, Make outcry—O city, Dispersed art thou Philistia, all of thee,—For out of the north, a smoke cometh in, With no straggler in his ranks.", "darby": "Howl, O gate! cry, O city! thou, Philistia, art wholly dissolved; for there cometh from the north a smoke, and none remaineth apart in his gatherings [of troops].", "twenty": "", "jps": "Howl, O gate; cry, O city; melt away, O Philistia, all of thee; for there cometh a smoke out of the north, and there is no straggler in his ranks.", "acv": "Howl, O gate, cry, O city. Thou are melted away, O Philistia, all of thee. For there comes a smoke out of the north, and there is no straggler in his ranks.", "anderson": "", "haweis": "", "noyes": "Howl, O gate! cry aloud, O city! O Philistia, thou meltest away in terror! For from the north cometh a smoke, And there is no straggler in their hosts.", "webster": "Howl, O gate; cry, O city; thou, all Palestina, [art] dissolved: for there shall come from the north a smoke, and none [shall be] alone in his appointed times.", "vulgate": "ulula porta clama civitas prostrata est Philisthea omnis ab aquilone enim fumus venit et non est qui effugiat agmen eius;", "brenton": "Howl, ye gates of cities; let the cities be troubled and cry, even all the Philistines: for smoke is coming from the north, and there is no possibility of living."}}, {"v": 32, "ref": "14:32", "o": "וּ/מַֽה יַּעֲנֶ֖ה מַלְאֲכֵי ג֑וֹי כִּ֤י יְהוָה֙ יִסַּ֣ד צִיּ֔וֹן וּ/בָ֥/הּ יֶחֱס֖וּ עֲנִיֵּ֥י עַמּֽ/וֹ", "en": {"kjv": "What shall one then answer the messengers of the nation? That the Lord hath founded Zion, and the poor of his people shall trust in it.", "web": "What will they answer the messengers of the nation? That Yahweh has founded Zion, and in her the afflicted of his people will take refuge.", "bsb": "What answer will be given to the envoys of that nation? “The LORD has founded Zion, where His afflicted people will find refuge.”", "asv": "What then shall one answer the messengers of the nation? That Jehovah hath founded Zion, and in her shall the afflicted of his people take refuge.", "ylt": "And what doth one answer the messengers of a nation? `That Jehovah hath founded Zion, And in it do the poor of His people trust!'", "dra": "And what shall be answered to the messengers of the nations? That the Lord hath founded Sion, and the poor of his people shall hope in him.", "bbe": "What answer, then, will my people give to the representatives of the nation? That the Lord is the builder of Zion, and she will be a safe place for the poor of his people.", "geneva": "What shall then one answere the messengers of the Gentiles? That the Lord hath stablished Zion, and the poore of his people shall trust in it.", "wycliffe": "And what schal be answerid to the messangeris of folk? for the Lord hath foundid Sion, and the pore men of his puple schulen hope in hym.", "rotherham": "What, then, shall one answer the messengers of a nation? That Yahweh, hath founded Zion, And in her, shall seek refuge the oppressed of his people.", "darby": "And what shall be answered to the messengers of the nation? That Jehovah hath founded Zion, and the afflicted of his people find refuge in it.", "twenty": "", "jps": "What then shall one answer the messengers of the nation? That HaShem hath founded Zion, and in her shall the afflicted of His people take refuge.", "acv": "What then shall a man answer the messengers of the nation? That Jehovah has founded Zion, and in her shall the afflicted of his people take refuge.", "anderson": "", "haweis": "", "noyes": "What answer shall be given to the messengers of the nations? That Jehovah hath founded Zion, And in her shall the poor of his people find refuge.", "webster": "What shall [one] then answer the messengers of the nation? That the LORD hath founded Zion, and the poor of his people shall trust in it.", "vulgate": "et quid respondebitur nuntiis gentis quia Dominus fundavit Sion et in ipsa sperabunt pauperes populi eius;", "brenton": "And what shall the kings of the nations answer? That the Lord has founded Sion, and by him the poor of the people shall be saved."}}]}, {"c": 15, "verses": [{"v": 1, "ref": "15:1", "o": "מַשָּׂ֖א מוֹאָ֑ב כִּ֠י בְּ/לֵ֞יל שֻׁדַּ֨ד עָ֤ר מוֹאָב֙ נִדְמָ֔ה כִּ֗י בְּ/לֵ֛יל שֻׁדַּ֥ד קִיר מוֹאָ֖ב נִדְמָֽה", "en": {"kjv": "The burden of Moab. Because in the night Ar of Moab is laid waste, and brought to silence; because in the night Kir of Moab is laid waste, and brought to silence;", "web": "The burden of Moab: for in a night, Ar of Moab is laid waste, and brought to nothing; for in a night Kir of Moab is laid waste, and brought to nothing.", "bsb": "This is the burden against Moab: Ar in Moab is ruined, destroyed in a night! Kir in Moab is devastated, destroyed in a night!", "asv": "The burden of Moab. For in a night Ar of Moab is laid waste, and brought to nought; for in a night Kir of Moab is laid waste, and brought to nought.", "ylt": "The burden of Moab. Because in a night destroyed was Ar of Moab--It hath been cut off, Because in a night destroyed was Kir of Moab--It hath been cut off.", "dra": "The burden of Moab. Because in the night Ar of Moab is laid waste, it is silent: because the wall of Moab is destroyed in the night, it is silent.", "bbe": "The word about Moab. For in a night Ar of Moab has become waste, and is seen no longer; for in a night Kir of Moab has become waste, and is seen no longer.", "geneva": "The burden of Moab. Surely Ar of Moab was destroied, and brought to silece in a night: surely Kir of Moab was destroied, and brought to silence in a night.", "wycliffe": "The birthun of Moab. For Ar was destried in niyt, Moab was stille; for the wal was distried in the niyt, Moab was stille.", "rotherham": "The oracle on Moab: Because, in a night, was laid waste Ar of Moab—destroyed! Because, in a night, was laid waste Kir of Moab—destroyed,", "darby": "The burden of Moab: For in the night of being laid waste, Ar of Moab is destroyed; for in the night of being laid waste, Kir of Moab is destroyed!", "twenty": "", "jps": "The burden of Moab. For in the night that Ar of Moab is laid waste, he is brought to ruin; for in the night that Kir of Moab is laid waste, he is brought to ruin.", "acv": "The burden of Moab. For in a night Ar of Moab is laid waste, and brought to nothing. For in a night Kir of Moab is laid waste, and brought to nothing.", "anderson": "", "haweis": "", "noyes": "The prophecy concerning Moab. Yea! in the night of assault was Ar of Moab a ruin! In the night of assault was Kir of Moab a ruin!", "webster": "The burden of Moab. Because in the night Ar of Moab is laid waste, [and] brought to silence; because in the night Kir of Moab is laid waste, [and] brought to silence;", "vulgate": "onus Moab quia nocte vastata est Ar Moab conticuit quia nocte vastatus est murus Moab conticuit;", "brenton": "THE WORD AGAINST THE LAND OF MOAB. By night the land of Moab shall be destroyed; for by night the wall of the land of Moab shall be destroyed."}}, {"v": 2, "ref": "15:2", "o": "עָלָ֨ה הַ/בַּ֧יִת וְ/דִיבֹ֛ן הַ/בָּמ֖וֹת לְ/בֶ֑כִי עַל נְב֞וֹ וְ/עַ֤ל מֵֽידְבָא֙ מוֹאָ֣ב יְיֵלִ֔יל בְּ/כָל רֹאשָׁ֣י/ו קָרְחָ֔ה כָּל זָקָ֖ן גְּרוּעָֽה", "en": {"kjv": "He is gone up to Bajith, and to Dibon, the high places, to weep: Moab shall howl over Nebo, and over Medeba: on all their heads shall be baldness, and every beard cut off.", "web": "They have gone up to Bayith, and to Dibon, to the high places, to weep. Moab wails over Nebo and over Medeba. Baldness is on all of their heads. Every beard is cut off.", "bsb": "Dibon goes up to its temple to weep at its high places. Moab wails over Nebo, as well as over Medeba. Every head is shaved, every beard is cut off.", "asv": "They are gone up to Bayith, and to Dibon, to the high places, to weep: Moab waileth over Nebo, and over Medeba; on all their heads is baldness, every beard is cut off.", "ylt": "He hath gone up to Bajith and Dibon, The high places--to weep, On Nebo and on Medeba Moab howleth, On all its heads is baldness, every beard cut off.", "dra": "The house is gone up, and Dibon to the high places to mourn over Nabo, and over Medaba, Moab hath howled: on all their heads shall be baldness, and every beard shall be shaven.", "bbe": "The daughter of Dibon has gone up to the high places, weeping: Moab is sounding her cry of sorrow over Nebo, and over Medeba: everywhere the hair of the head and of the face is cut off.", "geneva": "He shall goe vp to the temple, and to Dibon to the hie places to weepe: for Nebo and for Medeba shall Moab howle: vpon all their heades shalbe baldnesse, and euery beard shauen.", "wycliffe": "The kingis hous, and Dybon stieden to hiy places, in to weilyng; on Nabo, and on Medaba Moab schal yelle. In alle hedis therof schal be ballidnesse, and ech beerd schal be schauun.", "rotherham": "He hath gone up to Bayith and Dibon, to the high places, to weep,—On Nebo and on Medeba, Moab is howling, On all their heads, a baldness, Every beard, clipped.", "darby": "He is gone up to Bajith, and to Dibon, to the high places, to weep; Moab howleth over Nebo, and over Medeba; on all their heads is baldness, every beard is cut off.", "twenty": "", "jps": "He is gone up to Baith, and to Dibon, to the high places, to weep; upon Nebo, and upon Medeba, Moab howleth; on all their heads is baldness, every beard is shaven.", "acv": "They have gone up to Bayith, and to Dibon, to the high places, to weep. Moab wails over Nebo, and over Medeba. On all their heads is baldness. Every beard is cut off.", "anderson": "", "haweis": "", "noyes": "They go up to the temple, and to Dibon, to weep upon the high places; Upon Nebo and upon Medeba doth Moab howl; On every head is baldness, And every beard is shorn.", "webster": "He is gone up to Bajith, and to Dibon, the high places, to weep: Moab shall howl over Nebo, and over Medeba: on all their heads [shall be] baldness, [and] every beard shorn.", "vulgate": "ascendit domus et Dibon ad excelsa in planctum super Nabo et super Medaba Moab ululabit in cunctis capitibus eius calvitium omnis barba radetur;", "brenton": "Grieve for yourselves; for even Debon, where your altar is, shall be destroyed: thither shall ye go up to weep, over Nabau of the land of Moab: howl ye: baldness shall be on every head, and all arms shall be wounded."}}, {"v": 3, "ref": "15:3", "o": "בְּ/חוּצֹתָ֖י/ו חָ֣גְרוּ שָׂ֑ק עַ֣ל גַּגּוֹתֶ֧י/הָ וּ/בִ/רְחֹבֹתֶ֛י/הָ כֻּלֹּ֥/ה יְיֵלִ֖יל יֹרֵ֥ד בַּ/בֶּֽכִי", "en": {"kjv": "In their streets they shall gird themselves with sackcloth: on the tops of their houses, and in their streets, every one shall howl, weeping abundantly.", "web": "In their streets, they clothe themselves in sackcloth. In their streets and on their housetops, everyone wails, weeping abundantly.", "bsb": "In its streets they wear sackcloth; on the rooftops and in the public squares they all wail, falling down weeping.", "asv": "In their streets they gird themselves with sackcloth; on their housetops, and in their broad places, every one waileth, weeping abundantly.", "ylt": "In its out-places they girded on sackcloth, On its pinnacles, and in its broad places, Every one howleth--going down with weeping.", "dra": "In their streets they are girded with sackcloth: on the tops of their houses, and in their streets all shall howl and come down weeping.", "bbe": "In their streets they are covering themselves with haircloth: on the tops of their houses, and in their public places, there is crying and bitter weeping.", "geneva": "In their streetes shall they bee gilded with sackecloth: on the toppes of their houses, and in their streetes euery one shall howle, and come downe with weeping.", "wycliffe": "In the meetyng of thre weies therof thei ben gird in a sak, alle yellyng on the housis therof and in the stretis therof; it schal go doun in to wepyng.", "rotherham": "In their streets, have they girded them with sackcloth,—On their housetops, and in their broadways, every one is howling—melting in tears;", "darby": "In their streets they are girded with sackcloth; on their roofs, and in their broadways, every one howleth, melted into tears.", "twenty": "", "jps": "In their streets they gird themselves with sackcloth; on their housetops, and in their broad places, every one howleth, weeping profusely.", "acv": "In their streets they gird themselves with sackcloth. On their housetops, and in their broad places, everyone wails, weeping abundantly.", "anderson": "", "haweis": "", "noyes": "In their streets they gird themselves with sackcloth; On the tops of their houses and in their public walks every one howleth, And melteth away with weeping.", "webster": "In their streets they shall gird themselves with sackcloth: on the tops of their houses, and in their streets, every one shall howl, weeping abundantly.", "vulgate": "in triviis eius accincti sunt sacco super tecta eius et in plateis eius omnis ululat descendit in fletum;", "brenton": "Gird yourselves with sackcloth in her streets: and lament upon her roofs, and in her streets, and in her ways; howl all of you with weeping."}}, {"v": 4, "ref": "15:4", "o": "וַ/תִּזְעַ֤ק חֶשְׁבּוֹן֙ וְ/אֶלְעָלֵ֔ה עַד יַ֖הַץ נִשְׁמַ֣ע קוֹלָ֑/ם עַל כֵּ֗ן חֲלֻצֵ֤י מוֹאָב֙ יָרִ֔יעוּ נַפְשׁ֖/וֹ יָ֥רְעָה לּֽ/וֹ", "en": {"kjv": "And Heshbon shall cry, and Elealeh: their voice shall be heard even unto Jahaz: therefore the armed soldiers of Moab shall cry out; his life shall be grievous unto him.", "web": "Heshbon cries out with Elealeh. Their voice is heard even to Jahaz. Therefore the armed men of Moab cry aloud. Their souls tremble within them.", "bsb": "Heshbon and Elealeh cry out; their voices are heard as far as Jahaz. Therefore the soldiers of Moab cry out; their souls tremble within.", "asv": "And Heshbon crieth out, and Elealeh; their voice is heard even unto Jahaz: therefore the armed men of Moab cry aloud; his soul trembleth within him.", "ylt": "And cry doth Heshbon and Elealeh, Unto Jahaz heard hath been their voice, Therefore the armed ones of Moab do shout, His life hath been grievous to him.", "dra": "Hesebon shall cry, and Eleale, their voice is heard even to Jasa. For this shall the well appointed men of Moab howl, his soul shall howl to itself.", "bbe": "Heshbon is crying out, and Elealeh; their voice is sounding even to Jahaz: for this cause the heart of Moab is shaking; his soul is shaking with fear.", "geneva": "And Heshbon shall crie, and Elealeh: their voyce shall bee heard vnto Iahaz: therefore the warriers of Moab shall showt: the soule of euery one shall lament in him selfe.", "wycliffe": "Esebon schal crie, and Eleale, the vois of hem is herd `til to Jasa; on this thing the redi men of Moab schulen yelle, the soule therof schal yelle to it silf.", "rotherham": "And Heshbon, hath made outcry, and Elealeh, Unto Jahaz, hath been heard their voice,—For this cause, do the armed men of Moab roar, Every man’s soul, quivereth to him.", "darby": "And Heshbon crieth, and Elealeh: their voice is heard unto Jahaz. Therefore the armed men of Moab cry out: his soul trembleth in him.", "twenty": "", "jps": "And Heshbon crieth out, and Elealeh; their voice is heard even unto Jahaz; therefore the armed men of Moab cry aloud; his soul is faint within him.", "acv": "And Heshbon cries out, and Elealeh. Their voice is heard even to Jahaz. Therefore the armed men of Moab cry aloud. His soul trembles within him.", "anderson": "", "haweis": "", "noyes": "Heshbon and Elealah utter a cry; Even to Jahaz is their voice heard; Therefore the warriors of Moab shriek aloud; Their hearts tremble within them.", "webster": "And Heshbon shall cry, and Elealeh: their voice shall be heard [even] to Jahaz: therefore the armed soldiers of Moab shall cry out; his life shall be grievous to him.", "vulgate": "clamavit Esebon et Eleale usque Iasa audita est vox eorum super hoc expediti Moab ululabunt anima eius ululabit sibi;", "brenton": "For Esebon and Eleale have cried: their voice was heard to Jassa: therefore the loins of the region of Moab cry aloud; her soul shall know."}}, {"v": 5, "ref": "15:5", "o": "לִבִּ/י֙ לְ/מוֹאָ֣ב יִזְעָ֔ק בְּרִיחֶ֕/הָ עַד צֹ֖עַר עֶגְלַ֣ת שְׁלִשִׁיָּ֑ה כִּ֣י מַעֲלֵ֣ה הַ/לּוּחִ֗ית בִּ/בְכִי֙ יַֽעֲלֶה בּ֔/וֹ כִּ֚י דֶּ֣רֶךְ חוֹרֹנַ֔יִם זַעֲקַת שֶׁ֖בֶר יְעֹעֵֽרוּ", "en": {"kjv": "My heart shall cry out for Moab; his fugitives shall flee unto Zoar, an heifer of three years old: for by the mounting up of Luhith with weeping shall they go it up; for in the way of Horonaim they shall raise up a cry of destruction.", "web": "My heart cries out for Moab! Her nobles flee to Zoar, to Eglath Shelishiyah; for they go up by the ascent of Luhith with weeping; for on the way to Horonaim, they raise up a cry of destruction.", "bsb": "My heart cries out over Moab; her fugitives flee as far as Zoar, as far as Eglath-shelishiyah. With weeping they ascend the slope of Luhith; they lament their destruction on the road to Horonaim.", "asv": "My heart crieth out for Moab; her nobles flee unto Zoar, to Eglath-shelishi-yah: for by the ascent of Luhith with weeping they go up; for in the way of Horonaim they raise up a cry of destruction.", "ylt": "My heart is toward Moab, Cry do her fugitives unto Zoar, a heifer of the third year , For--the ascent of Luhith--With weeping he goeth up in it, For, in the way of Horonaim, A cry of destruction they wake up.", "dra": "My heart shall cry to Moab, the bars thereof shall flee unto Segor a heifer of three years old: for by the ascent of Luith they shall go up weeping: and in the way of Oronaim they shall lift up a cry of destruction.", "bbe": "My heart is crying out for Moab; her people go in flight to Zoar, and to Eglath-shelishiyah: for they go up with weeping by the slope of Luhith; on the way to Horonaim they send up a cry of destruction.", "geneva": "Mine heart shall crie for Moab: his fugitiues shall flee vnto Zoar, an heiffer of three yere olde: for they shall goe vp with weeping by the mounting vp of Luhith: and by the way of Horonaim they shall raise vp a crie of destruction.", "wycliffe": "Myn herte schal crie to Moab, the barris therof `til to Segor, a cow calf of thre yeer. For whi a wepere schal stie bi the stiyng of Luith, and in the weie of Oronaym thei schulen reise cry of sorewe.", "rotherham": "Mine own heart, for Moab continueth to make outcry, Her fugitive, as far as Zoar, is like a heifer of three years; For the accent of Luhith, with weeping, they ascend, For by the way of Horonaim—an outcry of destruction, they excite;", "darby": "My heart crieth out for Moab; their fugitives [have fled] unto Zoar, unto Eglath-Sheli-shijah: for by the ascent of Luhith, with weeping they go up by it; for in the way of Horonaim they raise up a cry of destruction.", "twenty": "", "jps": "My heart crieth out for Moab; her fugitives reach unto Zoar, a heifer of three years old; for by the ascent of Luhith with weeping they go up; for in the way of Horonaim they raise up a cry of destruction.", "acv": "My heart cries out for Moab. Her nobles flee to Zoar, to Eglath-shelishi-yah. For they go up with weeping by the ascent of Luhith. For they raise up a cry of destruction in the way of Horonaim.", "anderson": "", "haweis": "", "noyes": "My heart crieth out for Moab, Whose fugitives wander to Zoar, to Eglath-shelishijah; For they ascend the heights of Luhith weeping, And in the way of Horonaim they raise the cry of destruction.", "webster": "My heart shall cry out for Moab; his fugitives [shall flee] to Zoar, a heifer of three years old: for they shall go up the ascent of Luhith with weeping; for in the way of Horonaim they shall raise a cry of destruction.", "vulgate": "cor meum ad Moab clamabit vectes eius usque ad Segor vitulam conternantem per ascensum enim Luith flens ascendet et in via Oronaim clamorem contritionis levabunt;", "brenton": "The heart of the region of Moab cries within her to Segor; for it is as a heifer of three years old: and on the ascent of Luith they shall go up to thee weeping by the way of Aroniim: she cries, Destruction, and trembling."}}, {"v": 6, "ref": "15:6", "o": "כִּֽי מֵ֥י נִמְרִ֖ים מְשַׁמּ֣וֹת יִֽהְי֑וּ כִּֽי יָבֵ֤שׁ חָצִיר֙ כָּ֣לָה דֶ֔שֶׁא יֶ֖רֶק לֹ֥א הָיָֽה", "en": {"kjv": "For the waters of Nimrim shall be desolate: for the hay is withered away, the grass faileth, there is no green thing.", "web": "For the waters of Nimrim will be desolate; for the grass has withered away, the tender grass fails, there is no green thing.", "bsb": "The waters of Nimrim are dried up, and the grass is withered; the vegetation is gone, and the greenery is no more.", "asv": "For the waters of Nimrim shall be desolate; for the grass is withered away, the tender grass faileth, there is no green thing.", "ylt": "For, the waters of Nimrim are desolations, For, withered hath been the hay, Finished hath been the tender grass, A green thing there hath not been.", "dra": "For the waters of Nemrim shall be desolate, for the grass is withered away, the spring is faded, all the greenness is perished.", "bbe": "The waters of Nimrim will become dry: for the grass is burned up, the young grass is coming to an end, every green thing is dead.", "geneva": "For the waters of Nimrim shall be dried vp: therefore the grasse is withered, the herbes consumed, and there was no greene herbe.", "wycliffe": "For whi the watris of Nemrym schulen be forsakun; for the eerbe dried up, buriownyng failide, al grenenesse perischide.", "rotherham": "For, the waters of Nimrim, shall become desolation,—For grass, hath dried up, Herbage hath failed, Green thing, hath not sprung up!", "darby": "For the waters of Nimrim shall be desolate; for the herbage is withered away, the grass hath failed, there is no green thing.", "twenty": "", "jps": "For the Waters of Nimrim shall be desolate; for the grass is withered away, the herbage faileth, there is no green thing.", "acv": "For the waters of Nimrim shall be desolate, for the grass is withered away. The tender grass fails. There is no green thing.", "anderson": "", "haweis": "", "noyes": "For the waters of Nimrim are desolate; The grass is withered; the tender plant faileth; There is no green thing left.", "webster": "For the waters of Nimrim shall be desolate: for the herb is withered away, the grass faileth, there is no green thing.", "vulgate": "aquae enim Nemrim desertae erunt quia aruit herba defecit germen viror omnis interiit;", "brenton": "The water of Nemerim shall be desolate, and the grass thereof shall fail: for there shall be no green grass."}}, {"v": 7, "ref": "15:7", "o": "עַל כֵּ֖ן יִתְרָ֣ה עָשָׂ֑ה וּ/פְקֻדָּתָ֔/ם עַ֛ל נַ֥חַל הָ/עֲרָבִ֖ים יִשָּׂאֽוּ/ם", "en": {"kjv": "Therefore the abundance they have gotten, and that which they have laid up, shall they carry away to the brook of the willows.", "web": "Therefore they will carry away the abundance they have gotten, and that which they have stored up, over the brook of the willows.", "bsb": "So they carry their wealth and belongings over the Brook of the Willows.", "asv": "Therefore the abundance they have gotten, and that which they have laid up, shall they carry away over the brook of the willows.", "ylt": "Therefore the abundance he made, and their store, Unto the brook of the willows they carry.", "dra": "According to the greatness of their work, is their visitation also: they shall lead them to the torrent of the willows.", "bbe": "For this cause they will take away their wealth, and the stores they have got together, over the stream of the water-plants.", "geneva": "Therefore what euery man hath left, and their substance shall they beare to the brooke of the willowes.", "wycliffe": "Bi the greetnesse of werk, and the visityng of hem, to the stronde of salewis thei schulen lede hem.", "rotherham": "For this cause, the savings they had made and that which they had stored, Over the torrent-bed of the willows, shall they bear them.", "darby": "Therefore the abundance they have gotten, and that which they have laid up, do they carry away to the torrent of the willows.", "twenty": "", "jps": "Therefore the abundance they have gotten, and that which they have laid up, shall they carry away to the brook of the willows.", "acv": "Therefore the abundance they have gotten, and that which they have laid up, they shall carry away over the brook of the willows.", "anderson": "", "haweis": "", "noyes": "Wherefore the remnant of their substance and their wealth They shall carry to the brook of willows.", "webster": "Therefore the abundance they have gained, and that which they have laid up, shall they carry away to the brook of the willows.", "vulgate": "secundum magnitudinem operis et visitatio eorum ad torrentem salicum ducent eos;", "brenton": "Shall Moab even thus be delivered? for I will bring the Arabians upon the valley, and they shall take it."}}, {"v": 8, "ref": "15:8", "o": "כִּֽי הִקִּ֥יפָה הַ/זְּעָקָ֖ה אֶת גְּב֣וּל מוֹאָ֑ב עַד אֶגְלַ֨יִם֙ יִלְלָתָ֔/הּ וּ/בְאֵ֥ר אֵילִ֖ים יִלְלָתָֽ/הּ", "en": {"kjv": "For the cry is gone round about the borders of Moab; the howling thereof unto Eglaim, and the howling thereof unto Beer–elim.", "web": "For the cry has gone around the borders of Moab; its wailing to Eglaim, and its wailing to Beer Elim.", "bsb": "For their outcry echoes to the border of Moab. Their wailing reaches Eglaim; it is heard in Beer-elim.", "asv": "For the cry is gone round about the borders of Moab; the wailing thereof unto Eglaim, and the wailing thereof unto Beer-elim.", "ylt": "For gone round hath the cry the border of Moab, Unto Eglaim is its howling, And to Beer-Elim is its howling.", "dra": "For the cry is gone round about the border of Moab: the howling thereof unto Gallim, and unto the well of Elim the cry thereof.", "bbe": "For the cry has gone round the limits of Moab; as far as to Eglaim and Beer-elim.", "geneva": "For the crie went round about the borders of Moab: and the howling thereof vnto Eglaim, and the skriking thereof vnto Beer Elim,", "wycliffe": "For whi cry cumpasside the ende of Moab; `til to Galym the yellyng therof, and the cry therof `til to the pit of Helym.", "rotherham": "For the outcry hath gone round the boundary of Moab,—As far as Eglaim, the howling thereof, And to Beer-elim, the howling thereof.", "darby": "For the cry goeth round about the borders of Moab; the howling thereof unto Eglaim, and the howling thereof unto Beer-elim.", "twenty": "", "jps": "For the cry is gone round about the borders of Moab; the howling thereof unto Eglaim, and the howling thereof unto Beer-elim.", "acv": "For the cry has gone round about the borders of Moab, the wailing of it to Eglaim, and the wailing of it to Beer-elim.", "anderson": "", "haweis": "", "noyes": "For the cry encompasseth the borders of Moab; Even to Eglaim reacheth her wailing, To Beer-Elim her howling.", "webster": "For the cry hath gone round the borders of Moab, her howling to Eglaim, and her howling to Beer-elim.", "vulgate": "quoniam circumiit clamor terminum Moab usque ad Gallim ululatus eius et usque ad puteum Helim clamor eius;", "brenton": "For the cry has reached the border of the region of Moab, even of Agalim; and her howling has gone as far as the well of Aelim."}}, {"v": 9, "ref": "15:9", "o": "כִּ֣י מֵ֤י דִימוֹן֙ מָ֣לְאוּ דָ֔ם כִּֽי אָשִׁ֥ית עַל דִּימ֖וֹן נוֹסָפ֑וֹת לִ/פְלֵיטַ֤ת מוֹאָב֙ אַרְיֵ֔ה וְ/לִ/שְׁאֵרִ֖ית אֲדָמָֽה", "en": {"kjv": "For the waters of Dimon shall be full of blood: for I will bring more upon Dimon, lions upon him that escapeth of Moab, and upon the remnant of the land.", "web": "For the waters of Dimon are full of blood; for I will bring yet more on Dimon, a lion on those of Moab who escape, and on the remnant of the land.", "bsb": "The waters of Dimon are full of blood, but I will bring more upon Dimon— a lion upon the fugitives of Moab and upon the remnant of the land.", "asv": "For the waters of Dimon are full of blood; for I will bring yet more upon Dimon, a lion upon them of Moab that escape, and upon the remnant of the land.", "ylt": "For the waters of Dimon have been full of blood, For I set on Dimon additions, For the escaped of Moab a lion, And for the remnant of Adamah!", "dra": "For the waters of Dibon are filled with blood: for I will bring more upon Dibon: the lion upon them that shall flee of Moab, and upon the remnant of the land.", "bbe": "For the waters of Dimon are full of blood: and I'm sending even more on Moab, a lion on those of Moab who go in flight, and on the rest of the land.", "geneva": "Because the waters of Dimon shall be full of blood: for I will bring more vpon Dimon, euen lyons vpon him that escapeth of Moab, and to the remnant of the land.", "wycliffe": "For the watris of Dibon ben fillid with blood; for Y schal sette encreessyngis on Dibon, to tho men of Moab that fledden fro the lioun, and to the relifs of the lond.", "rotherham": "For the waters of Dimon, are full of blood, For I will lay upon Dimon new troubles,—To the escaped of Moab, the lions, Even to the survivors on the soil.", "darby": "For the waters of Dimon are full of blood, for I will lay yet more upon Dimon: a lion upon them that are escaped of Moab, and upon that which remaineth of the land.", "twenty": "", "jps": "For the waters of Dimon are full of blood; for I will bring yet more upon Dimon, a lion upon him that escapeth of Moab, and upon the remnant of the land.", "acv": "For the waters of Dimon are full of blood. For I will bring yet more upon Dimon, a lion upon those of Moab who escape, and upon the remnant of the land.", "anderson": "", "haweis": "", "noyes": "For the waters of Dimon are full of blood; For I bring new evils upon Dimon; Upon him that escapeth of Moab will I send a lion, Even upon him that remaineth in the land.", "webster": "For the waters of Dimon shall be full of blood: for I will bring more upon Dimon, lions upon him that escapeth of Moab, and upon the remnant of the land.", "vulgate": "quia aquae Dibon repletae sunt sanguine ponam enim super Dibon additamenta his qui fugerint de Moab leonem et reliquiis terrae;", "brenton": "And the water of Dimon shall be filled with blood: for I will bring Arabians upon Dimon, and I will take away the seed of Moab, and Ariel, and the remnant of Adama."}}]}, {"c": 16, "verses": [{"v": 1, "ref": "16:1", "o": "שִׁלְחוּ כַ֥ר מֹשֵֽׁל אֶ֖רֶץ מִ/סֶּ֣לַע מִדְבָּ֑רָ/ה אֶל הַ֖ר בַּת צִיּֽוֹן", "en": {"kjv": "Send ye the lamb to the ruler of the land from Sela to the wilderness, unto the mount of the daughter of Zion.", "web": "Send the lambs for the ruler of the land from Selah to the wilderness, to the mountain of the daughter of Zion.", "bsb": "Send the tribute lambs to the ruler of the land, from Sela in the desert to the mount of Daughter Zion.", "asv": "Send ye the lambs for the ruler of the land from Selah to the wilderness, unto the mount of the daughter of Zion.", "ylt": "Send ye a lamb to the ruler of the land, From Selah in the wilderness, Unto the mount of the daughter of Zion.", "dra": "Send forth, O Lord, the lamb, the ruler of the earth, from Petra of the desert, to the mount of the daughter of Sion.", "bbe": "And they will send ... to the mountain of the daughter of Zion.", "geneva": "Send yee a lambe to the ruler of the worlde from the rocke of the wildernesse, vnto the mountaine of the daughter Zion.", "wycliffe": "Lord, sende thou out a lomb, the lordli gouernour of erthe, fro the stoon of desert to the hil of the douyter of Sion.", "rotherham": "Send ye the lamb due to the ruler of the land, From Sela towards the desert,—Unto the mount of the daughter of Zion;", "darby": "Send the lamb of the ruler of the land from the rock to the wilderness, — unto the mount of the daughter of Zion.", "twenty": "", "jps": "Send ye the lambs for the ruler of the land from the crags that are toward the wilderness, unto the mount of the daughter of Zion.", "acv": "Send ye the lambs for the ruler of the land from Selah to the wilderness, to the mount of the daughter of Zion.", "anderson": "", "haweis": "", "noyes": "Send ye the lambs to the ruler of the land, From Selah through the wilderness To the mount of the daughter of Zion!", "webster": "Send ye the lamb to the ruler of the land from Sela to the wilderness, to the mount of the daughter of Zion.", "vulgate": "emitte agnum dominatorem terrae de Petra deserti ad montem filiae Sion;", "brenton": "I will send as it were reptiles on the land: is not the mount of the daughter of Sion a desolate rock?"}}, {"v": 2, "ref": "16:2", "o": "וְ/הָיָ֥ה כְ/עוֹף נוֹדֵ֖ד קֵ֣ן מְשֻׁלָּ֑ח תִּֽהְיֶ֨ינָה֙ בְּנ֣וֹת מוֹאָ֔ב מַעְבָּרֹ֖ת לְ/אַרְנֽוֹן", "en": {"kjv": "For it shall be, that, as a wandering bird cast out of the nest, so the daughters of Moab shall be at the fords of Arnon.", "web": "For it will be that as wandering birds, as a scattered nest, so will the daughters of Moab be at the fords of the Arnon.", "bsb": "Like fluttering birds pushed out of the nest, so are the daughters of Moab at the fords of the Arnon:", "asv": "For it shall be that, as wandering birds, as a scattered nest, so shall the daughters of Moab be at the fords of the Arnon.", "ylt": "And it hath come to pass, As a wandering bird, a nest cast out, Are daughters of Moab, at fords of Arnon.", "dra": "And it shall come to pass, that as a bird fleeing away, and as young ones flying out of the nest, so shall the daughters of Moab be in the passage of Arnon.", "bbe": "For the daughters of Moab will be like wandering birds, like a place from which the young birds have gone in flight, at the ways across the Arnon.", "geneva": "For it shall be as a birde that flieth, and a nest forsaken: the daughters of Moab shall be at the foordes of Arnon.", "wycliffe": "And it schal be as a foule fleynge, and briddis fleynge awei fro the nest, so schulen be the douytris of Moab in the passyng ouer of Arnon.", "rotherham": "Yet shall it be that—Like wandering birds from a nest cast forth, Shall be the daughters of Moab, at the fords of Arnon.", "darby": "And it shall be [that] as a wandering bird, [as] a scattered nest, so shall the daughters of Moab be at the fords of the Arnon.", "twenty": "", "jps": "For it shall be that, as wandering birds, as a scattered nest, so shall the daughters of Moab be at the fords of Arnon.", "acv": "For it shall be that, as wandering birds, as a scattered nest, so shall the daughters of Moab be at the fords of the Arnon.", "anderson": "", "haweis": "", "noyes": "For as a wandering bird, As a forthdriven nest, So shall be the daughters of Moab At the fords of Arnon; [saying,]", "webster": "For it shall be, [that], as a wandering bird cast out of the nest, [so] the daughters of Moab shall be at the fords of Arnon.", "vulgate": "et erit sicut avis fugiens et pulli de nido avolantes sic erunt filiae Moab in transcensu Arnon;", "brenton": "For thou shalt be as a young bird taken away from a bird that has flown: even thou shalt be so, daughter of Moab: and then do thou, O Arnon,"}}, {"v": 3, "ref": "16:3", "o": "הביאו הָבִ֤יאִי עֵצָה֙ עֲשׂ֣וּ פְלִילָ֔ה שִׁ֧יתִי כַ/לַּ֛יִל צִלֵּ֖/ךְ בְּ/ת֣וֹךְ צָהֳרָ֑יִם סַתְּרִי֙ נִדָּחִ֔ים נֹדֵ֖ד אַל תְּגַלִּֽי", "en": {"kjv": "Take counsel, execute judgment; make thy shadow as the night in the midst of the noonday; hide the outcasts; bewray not him that wandereth.", "web": "Give counsel! Execute justice! Make your shade like the night in the midst of the noonday! Hide the outcasts! Don’t betray the fugitive!", "bsb": "“Give us counsel; render a decision. Shelter us at noonday with shade as dark as night. Hide the refugees; do not betray the one who flees.", "asv": "Give counsel, execute justice; make thy shade as the night in the midst of the noonday; hide the outcasts; betray not the fugitive.", "ylt": "Bring ye in counsel, do judgment, Make as night thy shadow in the midst of noon, Hide outcasts, the wanderer reveal not.", "dra": "Take counsel, gather a council: make thy shadow as the night in the midday: hide them that flee, and betray not them that wander about.", "bbe": "Give wise directions, make a decision; let your shade be as night in full day: keep safe those who are in flight; do not give up the wandering ones.", "geneva": "Gather a cousel, execute iudgement: make thy shadowe as the night in the midday: hide them that are chased out: bewray not him that is fled.", "wycliffe": "Take thou councel, constreyne thou councel; sette thou as niyt thi schadewe in myddai, hide thou hem that fleen, and bitraye thou not men of vnstidfast dwellyng.", "rotherham": "Bring thou, in counsel, Execute thou judgment, Make as the night, thy shadow in the midst of high noon,—Hide thou the outcasts, The wanderer, do not thou reveal.", "darby": "Bring in counsel, execute justice; make thy shadow as the night in the midst of noonday; hide the outcasts, discover not the fugitive.", "twenty": "", "jps": "'Give counsel, execute justice; make thy shadow as the night in the midst of the noonday; hide the outcasts; betray not the fugitive.", "acv": "Give counsel, execute justice, make thy shade as the night in the midst of the noonday. Hide the outcasts. Do not betray the fugitive.", "anderson": "", "haweis": "", "noyes": "\"Offer counsel; give decision, Make thy shadow at noonday like the darkness of night. Hide the outcasts; Betray not the fugitives.", "webster": "Take counsel, execute judgment; make thy shadow as the night in the midst of the noon-day; hide the outcasts; discover not him that wandereth.", "vulgate": "ini consilium coge concilium pone quasi noctem umbram tuam in meridie absconde fugientes et vagos ne prodas;", "brenton": "take farther counsel, and continually make thou a shelter from grief: they flee in darkness at mid-day; they are amazed; be not thou led captive."}}, {"v": 4, "ref": "16:4", "o": "יָג֤וּרוּ בָ/ךְ֙ נִדָּחַ֔/י מוֹאָ֛ב הֱוִי סֵ֥תֶר לָ֖/מוֹ מִ/פְּנֵ֣י שׁוֹדֵ֑ד כִּֽי אָפֵ֤ס הַ/מֵּץ֙ כָּ֣לָה שֹׁ֔ד תַּ֥מּוּ רֹמֵ֖ס מִן הָ/אָֽרֶץ", "en": {"kjv": "Let mine outcasts dwell with thee, Moab; be thou a covert to them from the face of the spoiler: for the extortioner is at an end, the spoiler ceaseth, the oppressors are consumed out of the land.", "web": "Let my outcasts dwell with you! As for Moab, be a hiding place for him from the face of the destroyer. For the extortionist is brought to nothing. Destruction ceases. The oppressors are consumed out of the land.", "bsb": "Let my fugitives stay with you; be a refuge for Moab from the destroyer.” When the oppressor has gone, destruction has ceased, and the oppressors have vanished from the land,", "asv": "Let mine outcasts dwell with thee; as for Moab, be thou a covert to him from the face of the destroyer. For the extortioner is brought to nought, destruction ceaseth, the oppressors are consumed out of the land.", "ylt": "Sojourn in thee do My outcasts, O Moab, Be a secret hiding-place to them, From the face of a destroyer, For ceased hath the extortioner, Finished hath been a destroyer, Consumed the treaders down out of the land.", "dra": "My fugitives shall dwell with thee: O Moab, be thou a covert to them from the face of the destroyer: for the dust is at an end, the wretch is consumed: he hath failed, that trod the earth under foot.", "bbe": "Let those who have been forced out of Moab have a resting-place with you; be a cover to them from him who is making waste their land: till the cruel ones are cut off, and wasting has come to an end, and those who take pleasure in crushing the poor are gone from the land.", "geneva": "Let my banished dwell with thee: Moab be thou their couert from the face of the destroyer: for the extortioner shall ende: the destroyer shalbe consumed, and the oppressour shall cease out of the land.", "wycliffe": "My fleeris awei schulen dwelle at thee. Moab, be thou the hidyng place of hem fro the face of distriere. For whi dust is endid, the wretchid is wastid; he that defoulide the lond failude.", "rotherham": "Let mine own outcasts, sojourn with thee, O Moab, become thou a covert to them from the face of the spoiler,—For vanished is the oppressor, At an end is extortion, They who tread down have ceased out of the land.", "darby": "Let mine outcasts dwell with thee, Moab; be thou a covert to them from the face of the waster. For the extortioner is at an end, the wasting hath ceased, the oppressors are consumed out of the land.", "twenty": "", "jps": "Let mine outcasts dwell with thee; as for Moab, be thou a covert to him from the face of the spoiler.' For the extortion is at an end, spoiling ceaseth, they that trampled down are consumed out of the land;", "acv": "Let my outcasts dwell with thee. As for Moab, be thou a covert to him from the face of the destroyer. For the extortioner is brought to nothing. Destruction ceases. The oppressors are consumed out of the land.", "anderson": "", "haweis": "", "noyes": "Let my outcasts dwell with thee, [O Zion!] Be thou to them a covert from the spoiler! For the extortion is at an end, The spoiling ceaseth. The oppressors are consumed from the land.", "webster": "Let my outcasts dwell with thee, Moab; be thou a covert to them from the face of the spoiler: for the extortioner is at an end, the spoiler ceaseth, the oppressors are consumed out of the land.", "vulgate": "habitabunt apud te profugi mei Moab esto latibulum eorum a facie vastatoris finitus est enim pulvis consummatus est miser defecit qui conculcabat terram;", "brenton": "The fugitives of Moab shall sojourn with thee; they shall be to you a shelter from the face of the pursuer: for thine alliance has been taken away, and the oppressing ruler has perished from off the earth."}}, {"v": 5, "ref": "16:5", "o": "וְ/הוּכַ֤ן בַּ/חֶ֨סֶד֙ כִּסֵּ֔א וְ/יָשַׁ֥ב עָלָ֛י/ו בֶּ/אֱמֶ֖ת בְּ/אֹ֣הֶל דָּוִ֑ד שֹׁפֵ֛ט וְ/דֹרֵ֥שׁ מִשְׁפָּ֖ט וּ/מְהִ֥ר צֶֽדֶק", "en": {"kjv": "And in mercy shall the throne be established: and he shall sit upon it in truth in the tabernacle of David, judging, and seeking judgment, and hasting righteousness.", "web": "A throne will be established in loving kindness. One will sit on it in truth, in the tent of David, judging, seeking justice, and swift to do righteousness.", "bsb": "in loving devotion a throne will be established in the tent of David. A judge seeking justice and hastening righteousness will sit on it in faithfulness.", "asv": "And a throne shall be established in lovingkindness; and one shall sit thereon in truth, in the tent of David, judging, and seeking justice, and swift to do righteousness.", "ylt": "And established in kindness is the throne, And one hath sat on it in truth, in the tent of David, Judging and seeking judgment, and hasting righteousness.", "dra": "And a throne shall be prepared in mercy, and one shall sit upon it in truth in the tabernacle of David, judging and seeking judgment and quickly rendering that which is just.", "bbe": "Then a king's seat will be based on mercy, and one will be seated on it in the tent of David for ever; judging uprightly, and quick to do righteousness.", "geneva": "And in mercy shall the throne be prepared, and hee shall sit vpon it in stedfastnesse, in the tabernacle of Dauid, iudging, and seeking iudgement, and hasting iustice.", "wycliffe": "And the kyngis seete schal be maade redi in merci, and he schal sitte on it in treuthe, in the tabernacle of Dauid, demynge, and sekynge doom, and yeldynge swiftli that that is iust.", "rotherham": "So shall be established, in lovingkindness, a throne, And one shall sit thereon, in truth, in the home of David,—Judging—and seeking justice and speeding righteousness.", "darby": "And a throne shall be established in mercy: and in the tent of David there shall sit upon it, in truth, one judging and seeking justice and hastening righteousness.", "twenty": "", "jps": "And a throne is established through mercy, and there sitteth thereon in truth, in the tent of David, one that judgeth, and seeketh justice, and is ready in righteousness.", "acv": "And a throne shall be established in loving kindness, and he shall sit on it in truth, in the tent of David, judging, and seeking justice, and swift to do righteousness.", "anderson": "", "haweis": "", "noyes": "Then shall your throne be established through mercy, And upon it shall sit in the house of David A judge searching for justice, and prompt in equity.\"", "webster": "And in mercy shall the throne be established: and he shall sit upon it in truth in the tabernacle of David, judging, and seeking judgment, and hasting righteousness.", "vulgate": "et praeparabitur in misericordia solium et sedebit super eum in veritate in tabernaculo David iudicans et quaerens iudicium et velociter reddens quod iustum est;", "brenton": "And a throne shall be established with mercy; and one shall sit upon it with truth in the tabernacle of David, judging, and earnestly seeking judgments, and hasting righteousness."}}, {"v": 6, "ref": "16:6", "o": "שָׁמַ֥עְנוּ גְאוֹן מוֹאָ֖ב גֵּ֣א מְאֹ֑ד גַּאֲוָת֧/וֹ וּ/גְאוֹנ֛/וֹ וְ/עֶבְרָת֖/וֹ לֹא כֵ֥ן בַּדָּֽי/ו", "en": {"kjv": "We have heard of the pride of Moab; he is very proud: even of his haughtiness, and his pride, and his wrath: but his lies shall not be so.", "web": "We have heard of the pride of Moab, that he is very proud; even of his arrogance, his pride, and his wrath. His boastings are nothing.", "bsb": "We have heard of Moab’s pomposity, his exceeding pride and conceit, his overflowing arrogance. But his boasting is empty.", "asv": "We have heard of the pride of Moab, thathe is very proud; even of his arrogancy, and his pride, and his wrath; his boastings are nought.", "ylt": "We have heard of the pride of Moab--very proud, His pride, and his arrogance, and his wrath, Not right are his devices.", "dra": "We have heard of the pride of Moab, he is exceeding proud: his pride and his arrogancy, and his indignation is more than his strength.", "bbe": "We have had word of the pride of Moab, how great it is; how he is lifted up in pride and passion: his high words about himself are false.", "geneva": "We haue heard of the pride of Moab, (he is very proud) euen his pride, and his arrogancie, and his indignation, but his lies shall not be so.", "wycliffe": "We han herd the pride of Moab, he is ful proud; his pride, and his boost, and his indignacioun is more than his strengthe.", "rotherham": "We have heard of the arrogance of Moab, Proud exceedingly! His haughtiness and his arrogance and his passion, Not true, are his boastings.", "darby": "We have heard of the arrogance of Moab, — [he is] very proud, — of his pride, and his arrogance, and his wrath: his pratings are vain.", "twenty": "", "jps": "We have heard of the pride of Moab; he is very proud; even of his haughtiness, and his pride, and his arrogancy, his ill-founded boastings.", "acv": "We have heard of the pride of Moab, that he is very proud, even of his arrogance, and his pride, and his wrath. His boastings are nothing.", "anderson": "", "haweis": "", "noyes": "\"We have beard of the pride of Moab; he is very proud; His haughtiness, and his pride, and his insolence, His vain boastings.\"", "webster": "We have heard of the pride of Moab; [he is] very proud: [even] of his haughtiness, and his pride, and his wrath: [but] his lies [shall] not [be] so.", "vulgate": "audivimus superbiam Moab superbus est valde superbia eius et arrogantia eius et indignatio eius plus quam fortitudo eius;", "brenton": "We have heard of the pride of Moab; he is very proud. I have cut off his pride: thy prophecy shall not be thus, no not thus."}}, {"v": 7, "ref": "16:7", "o": "לָ/כֵ֗ן יְיֵלִ֥יל מוֹאָ֛ב לְ/מוֹאָ֖ב כֻּלֹּ֣/ה יְיֵלִ֑יל לַ/אֲשִׁישֵׁ֧י קִיר חֲרֶ֛שֶׂת תֶּהְגּ֖וּ אַךְ נְכָאִֽים", "en": {"kjv": "Therefore shall Moab howl for Moab, every one shall howl: for the foundations of Kir–hareseth shall ye mourn; surely they are stricken.", "web": "Therefore Moab will wail for Moab. Everyone will wail. You will mourn for the raisin cakes of Kir Hareseth, utterly stricken.", "bsb": "Therefore let Moab wail; let them wail together for Moab. Moan for the raisin cakes of Kir-hareseth, you who are utterly stricken.", "asv": "Therefore shall Moab wail for Moab, every one shall wail: for the raisin-cakes of Kir-hareseth shall ye mourn, utterly stricken.", "ylt": "Therefore howl doth Moab for Moab, all of it doth howl, For the grape-cakes of Kir-Hareseth it meditateth, Surely they are smitten.", "dra": "Therefore shall Moab howl to Moab, every one shall howl: to them that rejoice upon the brick walls, tell ye their stripes.", "bbe": "For this cause everyone in Moab will give cries of grief for Moab: crushed to the earth, they will be weeping for the men of Kir-hareseth.", "geneva": "Therefore shall Moab howle vnto Moab: euery one shall howle: for the foundations of Kirhareseth shall ye mourne, yet they shalbe striken.", "wycliffe": "Therfor Moab schal yelle to Moab, al Moab shal yelle to hem that ben glad on the wallis of bakun tijl stoon; speke ye her woundis.", "rotherham": "Therefore shall, Moab, howl for, Moab, All that belong to her, shall wail,—For the ruins of Kir-hareseth, shall they moan out Utterly stricken!", "darby": "Therefore shall Moab howl for Moab; every one of them shall howl. For the foundations of Kirhareseth shall ye mourn, verily afflicted.", "twenty": "", "jps": "Therefore shall Moab wail for Moab, every one shall wail; for the sweet cakes of Kir-hareseth shall ye mourn, sorely stricken.", "acv": "Therefore Moab shall wail for Moab, everyone shall wail. Ye shall mourn for the raisin-cakes of Kir-hareseth, utterly stricken.", "anderson": "", "haweis": "", "noyes": "Therefore shall Moab howl for Moab; Every one shall howl; For the ruins of Kir-hares shall ye mourn, In deep affliction.", "webster": "Therefore shall Moab howl for Moab, every one shall howl: for the foundations of Kir-hareseth shall ye mourn; surely [they are] stricken.", "vulgate": "idcirco ululabit Moab ad Moab universus ululabit his qui laetantur super muro cocti lateris loquimini plagas suas;", "brenton": "Moab shall howl; for all shall howl in the land of Moab: but thou shalt care for them that dwell in Seth, and thou shalt not be ashamed."}}, {"v": 8, "ref": "16:8", "o": "כִּ֣י שַׁדְמוֹת֩ חֶשְׁבּ֨וֹן אֻמְלָ֜ל גֶּ֣פֶן שִׂבְמָ֗ה בַּעֲלֵ֤י גוֹיִם֙ הָלְמ֣וּ שְׂרוּקֶּ֔י/הָ עַד יַעְזֵ֥ר נָגָ֖עוּ תָּ֣עוּ מִדְבָּ֑ר שְׁלֻ֣חוֹתֶ֔י/הָ נִטְּשׁ֖וּ עָ֥בְרוּ יָֽם", "en": {"kjv": "For the fields of Heshbon languish, and the vine of Sibmah: the lords of the heathen have broken down the principal plants thereof, they are come even unto Jazer, they wandered through the wilderness: her branches are stretched out, they are gone over the sea.", "web": "For the fields of Heshbon languish with the vine of Sibmah. The lords of the nations have broken down its choice branches, which reached even to Jazer, which wandered into the wilderness. Its shoots were spread abroad. They passed over the sea.", "bsb": "For the fields of Heshbon have withered, along with the grapevines of Sibmah. The rulers of the nations have trampled its choicest vines, which had reached as far as Jazer and spread toward the desert. Their shoots had spread out and passed over the sea.", "asv": "For the fields of Heshbon languish, and the vine of Sibmah; the lords of the nations have broken down the choice branches thereof, which reached even unto Jazer, which wandered into the wilderness; its shoots were spread abroad, they passed over the sea.", "ylt": "Because fields of Heshbon languish, The vine of Sibmah, Lords of nations did beat her choice vines, Unto Jazer they have come, They have wandered in a wilderness, Her plants have spread themselves, They have passed over a sea.", "dra": "For the suburbs of Hesebon are desolate, and the lords of the nations have destroyed the vineyard of Sabama: the branches thereof have reached even to Jazer: they have wandered in the wilderness, the branches thereof are left, they are gone over the sea.", "bbe": "For the fields of Heshbon are waste, the vine of Sibmah is dead; the lords of nations were overcome by the produce of her vines; her vine-plants went as far as Jazer, and came even to the waste land; her branches were stretched out to the sea.", "geneva": "For ye vineyards of Heshbon are cut downe, and the vine of Sibmah: the lordes of the heathen haue broken the principal vines thereof: they are come vnto Iaazer: they wandred in the wildernesse: her goodly branches stretched out them selues, and went ouer the sea.", "wycliffe": "For whi the subarbis of Esebon and the vyner of Sabama ben forsakun. The lordis of hethene men han kit doun the siouns therof; thei camen `til to Jaser, thei erriden in desert. The bowis therof ben forsakun, thei passiden the see.", "rotherham": "For, the fields of Heshbon are withered—The vine of Sibmah, the owners of nations, have broken off ruddy branches, Unto Jazer, had they reached, They had spread abroad to the desert,—Her boughs, had stretched forth, had gone over to the sea.", "darby": "For the fields of Heshbon languish, the vine of Sibmah; the lords of the nations have broken down its choice plants: they reached unto Jaazer, they wandered [through] the wilderness; its shoots stretched out, they went beyond the sea.", "twenty": "", "jps": "For the fields of Heshbon languish, and the vine of Sibmah, whose choice plants did overcome the lords of nations; they reached even unto Jazer, they wandered into the wilderness; her branches were spread abroad, they passed over the sea.", "acv": "For the fields of Heshbon languish, and the vine of Sibmah. The lords of the nations have broken down the choice branches of it, which reached even to Jazer, which wandered into the wilderness. Its shoots were spread abroad. They passed over the sea.", "anderson": "", "haweis": "", "noyes": "For the fields of Heshbon languish, The lords of the nations break down the choicest shoots of the vine of Sibmah, They reached even to Jazer; they wandered into the desert; Her branches were spread out; they crossed the sea.", "webster": "For the fields of Heshbon languish, [and] the vine of Sibmah: the lords of the heathen have broken down her principal plants, they have come [even] to Jazer, they wandered [through] the wilderness: her branches are extended, they have gone over the sea.", "vulgate": "quoniam suburbana Esebon deserta sunt et vinea Sabama domini gentium exciderunt flagella eius usque ad Iazer pervenerunt erraverunt in deserto propagines eius relictae sunt transierunt mare;", "brenton": "The plains of Esebon shall mourn, the vine of Sebama: swallowing up the nations, trample ye her vines, even to Jazer: ye shall not come together; wander ye in the desert: they that were sent are deserted, for they have gone over to the sea."}}, {"v": 9, "ref": "16:9", "o": "עַל כֵּ֡ן אֶבְכֶּ֞ה בִּ/בְכִ֤י יַעְזֵר֙ גֶּ֣פֶן שִׂבְמָ֔ה אֲרַיָּ֨וֶ/ךְ֙ דִּמְעָתִ֔/י חֶשְׁבּ֖וֹן וְ/אֶלְעָלֵ֑ה כִּ֧י עַל קֵיצֵ֛/ךְ וְ/עַל קְצִירֵ֖/ךְ הֵידָ֥ד נָפָֽל", "en": {"kjv": "Therefore I will bewail with the weeping of Jazer the vine of Sibmah: I will water thee with my tears, O Heshbon, and Elealeh: for the shouting for thy summer fruits and for thy harvest is fallen.", "web": "Therefore I will weep with the weeping of Jazer for the vine of Sibmah. I will water you with my tears, Heshbon, and Elealeh: for on your summer fruits and on your harvest the battle shout has fallen.", "bsb": "So I weep with Jazer for the vines of Sibmah; I drench Heshbon and Elealeh with my tears. Triumphant shouts have fallen silent over your summer fruit and your harvest.", "asv": "Therefore I will weep with the weeping of Jazer for the vine of Sibmah; I will water thee with my tears, O Heshbon, and Elealeh: for upon thy summer fruits and upon thy harvest the battle shout is fallen.", "ylt": "Therefore I weep with the weeping of Jazer, The vine of Sibmah, I water thee with my tear, O Heshbon and Elealeh, For--for thy summer fruits, and for thy harvest, The shouting hath fallen.", "dra": "Therefore I will lament with the weeping of Jazer the vineyard of Sabama: I will water thee with my tears, O Hesebon, and Eleale: for the voice of the treaders hath rushed in upon thy vintage, and upon thy harvest.", "bbe": "For this cause my sorrow for the vine of Sibmah will be like the weeping for Jazer: my eyes are dropping water on you, O Heshbon and Elealeh! For they are sounding the war-cry over your summer fruits and the getting in of your grain;", "geneva": "Therefore will I weepe with the weeping of Iaazer, and of the vine of Sibmah, O Heshbon: and Elealeh, I will make thee drunke with my teares, because vpon thy sommer fruits, and vpon thy haruest a showting is fallen.", "wycliffe": "On this thing Y schal wepe in the weping of Jaser, and on the vyner of Sabama. Esebon and Eleale, Y schal fille thee with my teer; for the vois of defouleris fellen on thi vyndage, and on thi heruest.", "rotherham": "For this cause, will I bewail, in the wailing of Jazer, The vine of Sibmah, I will drench thee with my tears, O Heshbon and Elealeh,—For, upon thy fruit-harvest, and upon thy grain-harvest, the battle-shout, hath fallen.", "darby": "Therefore I will weep with the weeping of Jaazer for the vine of Sibmah; with my tears will I water thee, Heshbon, and Elealeh, for a cry is fallen upon thy summer fruits and upon thy harvest.", "twenty": "", "jps": "Therefore I will weep with the weeping of Jazer for the vine of Sibmah; I will water thee with my tears, O Heshbon, and Elealeh; for upon thy summer fruits and upon thy harvest the battle shout is fallen.", "acv": "Therefore I will weep with the weeping of Jazer for the vine of Sibmah. I will water thee with my tears, O Heshbon, and Elealeh. for upon thy summer fruits and upon thy harvest the battle shout has fallen.", "anderson": "", "haweis": "", "noyes": "Therefore I will weep, like Jazer, for the vine of Sibmah; I will water thee with my tears, O Heshbon and Elealah, For upon thy summer fruits, and thy harvest, the war-shout is fallen.", "webster": "Therefore I will bewail with the weeping of Jazer the vine of Sibmah: I will water thee with my tears, O Heshbon, and Elealeh: for the shouting for thy summer fruits and for thy harvest is fallen.", "vulgate": "super hoc plorabo in fletu Iazer vineam Sabama inebriabo te lacrima mea Esebon et Eleale quoniam super vindemiam tuam et super messem tuam vox calcantium inruit;", "brenton": "Therefore will I weep as with the weeping of Jazer for the vine of Sebama; Esebon and Eleale have cast down thy trees; for I will trample on thy harvest and on thy vintages, and all thy plants shall fall."}}, {"v": 10, "ref": "16:10", "o": "וְ/נֶאֱסַ֨ף שִׂמְחָ֤ה וָ/גִיל֙ מִן הַ/כַּרְמֶ֔ל וּ/בַ/כְּרָמִ֥ים לֹֽא יְרֻנָּ֖ן לֹ֣א יְרֹעָ֑ע יַ֗יִן בַּ/יְקָבִ֛ים לֹֽא יִדְרֹ֥ךְ הַ/דֹּרֵ֖ךְ הֵידָ֥ד הִשְׁבַּֽתִּי", "en": {"kjv": "And gladness is taken away, and joy out of the plentiful field; and in the vineyards there shall be no singing, neither shall there be shouting: the treaders shall tread out no wine in their presses; I have made their vintage shouting to cease.", "web": "Gladness is taken away, and joy out of the fruitful field; and in the vineyards there will be no singing, neither joyful noise. Nobody will tread out wine in the presses. I have made the shouting stop.", "bsb": "Joy and gladness are removed from the orchard; no one sings or shouts in the vineyards. No one tramples the grapes in the winepresses; I have put an end to the cheering.", "asv": "And gladness is taken away, and joy out of the fruitful field; and in the vineyards there shall be no singing, neither joyful noise: no treader shall tread out wine in the presses; I have made the vintage shout to cease.", "ylt": "And removed have been gladness and joy from the fruitful field, And in vineyards they sing not, nor shout, Wine in the presses treadeth not the treader, Shouting I have caused to cease.", "dra": "And gladness and joy shall be taken away from Carmel, and there shall be no rejoicing nor shouting in the vineyards. He shall not tread out wine in the press that was wont to tread it out: the voice of the treaders I have taken away.", "bbe": "And all joy is gone; no longer are they glad for the fertile field; and in the vine-gardens there are no songs or sounds of joy: the crushing of grapes has come to an end, and its glad cry has been stopped.", "geneva": "And gladnes is taken away, and ioy out of the plentifull fielde: and in the vineyardes shall be no singing nor shouting for ioy: the treader shall not tread wine in the wine presses: I haue caused the reioycing to cease.", "wycliffe": "And gladnesse and ful out ioiyng schal be takun awei fro Carmele; and noon schal make ful out ioye, nether schal synge hertli song in vyneris. He that was wont to wringe out, schal not wrynge out wyn in a pressour; Y haue take awei the vois of wryngeris out.", "rotherham": "Now shall be withdrawn rejoicing and exultation out of the garden-land, And, in the vineyards, shall be neither singing nor shouting,—Wine in the winepress, the treader, shall not tread, The vintage-shout, have I made to cease.", "darby": "And joy and gladness is taken away out of the fruitful field; and in the vineyards there is no singing, neither is there shouting: the treaders tread out no wine in the presses, I have made the cry [of the winepress] to cease.", "twenty": "", "jps": "And gladness and joy are taken away out of the fruitful field; and in the vineyards there shall be no singing, neither shall there be shouting; no treader shall tread out wine in the presses; I have made the vintage shout to cease.", "acv": "And gladness is taken away, and joy out of the fruitful field. And in the vineyards there shall be no singing nor joyful noise. No treader shall tread out wine in the presses. I have made the vintage shout to cease.", "anderson": "", "haweis": "", "noyes": "Gladness and joy are driven from the fruitful field, And in the vineyards is no singing nor shouting; The treaders tread out no wine in their vats; I have made the vintage-shouting to cease.", "webster": "And gladness is taken away, and joy from the plentiful field; and in the vineyards there shall be no singing, neither shall there be shouting: the treaders shall tread out no wine in [their] presses; I have made [their vintage]-shouting to cease.", "vulgate": "et auferetur laetitia et exultatio de Carmelo et in vineis non exultabit neque iubilabit vinum in torculari non calcabit qui calcare consueverat vocem calcantium abstuli;", "brenton": "And gladness and rejoicing shall be taken away from the vineyards; and they shall not at all tread wine into the vats; for the vintage has ceased."}}, {"v": 11, "ref": "16:11", "o": "עַל כֵּן֙ מֵעַ֣/י לְ/מוֹאָ֔ב כַּ/כִּנּ֖וֹר יֶֽהֱמ֑וּ וְ/קִרְבִּ֖/י לְ/קִ֥יר חָֽרֶשׂ", "en": {"kjv": "Wherefore my bowels shall sound like an harp for Moab, and mine inward parts for Kir–haresh.", "web": "Therefore my heart sounds like a harp for Moab, and my inward parts for Kir Heres.", "bsb": "Therefore my heart laments for Moab like a harp, my inmost being for Kir-heres.", "asv": "Wherefore my heart soundeth like a harp for Moab, and mine inward parts for Kir-heres.", "ylt": "Therefore my bowels for Moab as a harp do sound, And mine inward parts for Kir-Haresh.", "dra": "Wherefore my bowels shall sound like a harp for Moab, and my inward parts for the brick wall.", "bbe": "For this cause the cords of my heart are sounding for Moab, and I am full of sorrow for Kir-heres.", "geneva": "Wherefore, my bowels shall sounde like an harpe for Moab, and mine inwarde partes for Ker-haresh.", "wycliffe": "On this thing my wombe schal sowne as an harpe to Moab, and myn entrails to the wal of bakun tiel stoon.", "rotherham": "For this cause, mine inward parts—for Moab, like a lyre, shall make a plaintive sound,—Yea what is within me, for Kir-heres.", "darby": "Therefore my bowels sound like a harp for Moab, and mine inward parts for Kirheres.", "twenty": "", "jps": "Wherefore my heart moaneth like a harp for Moab, and mine inward parts for Kir-heres.", "acv": "Therefore my heart sounds like a harp for Moab, and my inward parts for Kir-heres.", "anderson": "", "haweis": "", "noyes": "Therefore shall my bowels sound like a harp for Moab, And my inward parts for Kir-hares.", "webster": "Wherefore my bowels shall sound like a harp for Moab, and my inward parts for Kir-haresh.", "vulgate": "super hoc venter meus ad Moab quasi cithara sonabit et viscera mea ad murum cocti lateris;", "brenton": "Therefore my belly shall sound as a harp for Moab, and thou hast repaired my inward parts as a wall."}}, {"v": 12, "ref": "16:12", "o": "וְ/הָיָ֧ה כִֽי נִרְאָ֛ה כִּֽי נִלְאָ֥ה מוֹאָ֖ב עַל הַ/בָּמָ֑ה וּ/בָ֧א אֶל מִקְדָּשׁ֛/וֹ לְ/הִתְפַּלֵּ֖ל וְ/לֹ֥א יוּכָֽל", "en": {"kjv": "And it shall come to pass, when it is seen that Moab is weary on the high place, that he shall come to his sanctuary to pray; but he shall not prevail.", "web": "It will happen that when Moab presents himself, when he wearies himself on the high place, and comes to his sanctuary to pray, that he will not prevail.", "bsb": "When Moab appears on the high place, when he wearies himself and enters his sanctuary to pray, it will do him no good.", "asv": "And it shall come to pass, when Moab presenteth himself, when he wearieth himself upon the high place, and shall come to his sanctuary to pray, that he shall not prevail.", "ylt": "And it hath come to pass, when it hath been seen, That weary hath been Moab on the high place, And he hath come unto his sanctuary to pray, And is not able.", "dra": "And it shall come to pass, when it is seen that Moab is wearied on his high places, that he shall go in to his sanctuaries to pray, and shall not prevail.", "bbe": "And when Moab goes up to the high place, and makes prayer in the house of his god, it will have no effect.", "geneva": "And when it shall appeare that Moab shall be wearie of his hie places, then shall hee come to his temple to praie, but he shall not preuaile.", "wycliffe": "And it schal be, whanne it schal appere, that Moab hath trauelid on hise places, it schal entre to hise hooli thingis, that it biseche, and it schal not be worth.", "rotherham": "And it shall be—When it is seen that Moab hath laboured in vain on the high place, He shall enter into his holy place to pray, and shall not prevail,", "darby": "And it shall come to pass, when Moab shall appear, shall weary himself on the high place, and enter into his sanctuary to pray, that he shall not prevail.", "twenty": "", "jps": "And it shall come to pass, when it is seen that Moab hath wearied himself upon the high place, that he shall come to his sanctuary to pray; but he shall not prevail", "acv": "And it shall come to pass, when Moab presents himself, when he wearies himself upon the high place, and shall come to his sanctuary to pray, that he shall not prevail.", "anderson": "", "haweis": "", "noyes": "And it shall come to pass that though Moab present himself, Though he weary himself upon his high places, And go up to his sanctuary to pray, Yet shall he not prevail.", "webster": "And it shall come to pass, when it is seen that Moab is weary on the high place, that he shall come to his sanctuary to pray; but he shall not prevail.", "vulgate": "et erit cum apparuerit quod laboravit Moab super excelsis suis ingredietur ad sancta sua ut obsecret et non valebit;", "brenton": "And it shall be to thy shame, (for Moab is wearied at the altars,) that he shall go in to the idols thereof to pray, but they shall not be at all able to deliver him."}}, {"v": 13, "ref": "16:13", "o": "זֶ֣ה הַ/דָּבָ֗ר אֲשֶׁ֨ר דִּבֶּ֧ר יְהוָ֛ה אֶל מוֹאָ֖ב מֵ/אָֽז", "en": {"kjv": "This is the word that the Lord hath spoken concerning Moab since that time.", "web": "This is the word that Yahweh spoke concerning Moab in time past.", "bsb": "This is the message that the LORD spoke earlier concerning Moab.", "asv": "This is the word that Jehovah spake concerning Moab in time past.", "ylt": "This is the word that Jehovah hath spoken unto Moab from that time,", "dra": "This is the word, that the Lord spoke to Moab from that time:", "bbe": "This is the word which the Lord said about Moab in the past.", "geneva": "This is the word that the Lord hath spoken against Moab since that time.", "wycliffe": "This is the word which the Lord spak to Moab fro that tyme.", "rotherham": "This, is the word which Yahweh spake concerning Moab in, time past;", "darby": "This is the word which Jehovah hath spoken from of old concerning Moab.", "twenty": "", "jps": "This is the word that HaShem spoke concerning Moab in time past.", "acv": "This is the word that Jehovah spoke concerning Moab in time past.", "anderson": "", "haweis": "", "noyes": "This is the word which Jehovah spake concerning Moab of old.", "webster": "This [is] the word that the LORD hath spoken concerning Moab since that time.", "vulgate": "hoc verbum quod locutus est Dominus ad Moab ex tunc;", "brenton": "This is the word which the Lord spoke against Moab, when he spoke."}}, {"v": 14, "ref": "16:14", "o": "וְ/עַתָּ֗ה דִּבֶּ֣ר יְהוָה֮ לֵ/אמֹר֒ בְּ/שָׁלֹ֤שׁ שָׁנִים֙ כִּ/שְׁנֵ֣י שָׂכִ֔יר וְ/נִקְלָה֙ כְּב֣וֹד מוֹאָ֔ב בְּ/כֹ֖ל הֶ/הָמ֣וֹן הָ/רָ֑ב וּ/שְׁאָ֥ר מְעַ֛ט מִזְעָ֖ר ל֥וֹא כַבִּֽיר", "en": {"kjv": "But now the Lord hath spoken, saying, Within three years, as the years of an hireling, and the glory of Moab shall be contemned, with all that great multitude; and the remnant shall be very small and feeble.", "web": "But now Yahweh has spoken, saying, “Within three years, as a worker bound by contract would count them, the glory of Moab shall be brought into contempt, with all his great multitude; and the remnant will be very small and feeble.”", "bsb": "And now the LORD says, “In three years, as a hired worker counts the years, Moab’s splendor will become an object of contempt, with all her many people. And those who are left will be few and feeble.”", "asv": "But now Jehovah hath spoken, saying, Within three years, as the years of a hireling, the glory of Moab shall be brought into contempt, with all his great multitude; and the remnant shall be very small and of no account.", "ylt": "And now hath Jehovah spoken, saying, `In three years, as years of an hireling, Lightly esteemed is the honour of Moab, With all the great multitude, And the remnant is little, small, not mighty!'", "dra": "And now the Lord hath spoken, saying: In three years, as the years of a hireling, the glory of Moab shall be taken away for all the multitude of the people, and it shall be left small and feeble, not many.", "bbe": "But now the Lord has said, In three years, the years of a servant working for payment, the glory of Moab, all that great people, will be turned to shame, and the rest of Moab will be very small and without honour.", "geneva": "And nowe the Lord hath spoken, saying, In three yeres, as the yeeres of a hireling, and the glorie of Moab shall be contemned in all the great multitude, and the remnant shalbe very small and feeble.", "wycliffe": "And now the Lord spak, seiynge, In thre yeer that weren as the yeeris of an hirid man, the glorie of Moab schal be takun awei on al the myche puple; and ther schal be left in it as a litil rasyn, and a litil, and not myche.", "rotherham": "But now, hath Yahweh spoken saying, In three years,—as the years of a hireling, shall the glory of Moab be diminished, with all the great multitude,—even a very small remnant, of no account.", "darby": "And now Jehovah speaketh saying, Within three years, as the years of a hired servant, and the glory of Moab shall be brought to nothing, with all that great multitude; and the remnant shall be small, few, of no account.", "twenty": "", "jps": "But now HaShem hath spoken, saying: 'Within three years, as the years of a hireling, and the glory of Moab shall wax contemptible for all his great multitude; and the remnant shall be very small and without strength.'", "acv": "But now Jehovah has spoken, saying, Within three years, as the years of a hireling, the glory of Moab shall be brought into contempt, with all his great multitude. And the remnant shall be very small and of no account.", "anderson": "", "haweis": "", "noyes": "But now saith Jehovah: Within three years, like the years of a hireling, The glory of Moab shall be put to shame, With all his great multitude; And the remnant shall be very small, and without strength.", "webster": "But now the LORD hath spoken, saying, Within three years, as the years of a hireling, and the glory of Moab shall be contemned, with all that great multitude; and the remnant [shall be] very small [and] feeble.", "vulgate": "et nunc locutus est Dominus dicens in tribus annis quasi anni mercennarii auferetur gloria Moab super omni populo multo et relinquetur parvus et modicus nequaquam multus;", "brenton": "And now I say, in three years, of the years of an hireling, the glory of Moab shall be dishonoured with all his great wealth; and he shall be left few in number, and not honoured."}}]}, {"c": 17, "verses": [{"v": 1, "ref": "17:1", "o": "מַשָּׂ֖א דַּמָּ֑שֶׂק הִנֵּ֤ה דַמֶּ֨שֶׂק֙ מוּסָ֣ר מֵ/עִ֔יר וְ/הָיְתָ֖ה מְעִ֥י מַפָּלָֽה", "en": {"kjv": "The burden of Damascus. Behold, Damascus is taken away from being a city, and it shall be a ruinous heap.", "web": "The burden of Damascus: “Behold, Damascus is taken away from being a city, and it will be a ruinous heap.", "bsb": "This is the burden against Damascus: “Behold, Damascus is no longer a city; it has become a heap of ruins.", "asv": "The burden of Damascus. Behold, Damascus is taken away from being a city, and it shall be a ruinous heap.", "ylt": "The burden of Damascus. Lo, Damascus is taken away from being a city, And it hath been a heap--a ruin.", "dra": "The burden of Damascus. Behold Damascus shall cease to be a city, and shall be as a ruinous heap of stones.", "bbe": "The word about Damascus. See, they have made Damascus a town no longer; it has become a waste place.", "geneva": "The burden of Damascus. Beholde, Damascus is taken away from being a citie, for it shall be a ruinous heape.", "wycliffe": "The birthun of Damask. Lo! Damask schal faile to be a citee, and it schal be as an heep of stoonys in fallyng.", "rotherham": "The oracle on Damascus,—Lo! Damascus, is to be removed from being a city, And shall become a heap of ruins:", "darby": "The burden of Damascus. Behold, Damascus is taken away from [being] a city, and it shall be a ruinous heap.", "twenty": "", "jps": "The burden of Damascus. Behold, Damascus is taken away from being a city, and it shall be a ruinous heap.", "acv": "The burden of Damascus. Behold, Damascus is taken away from being a city, and it shall be a ruinous heap.", "anderson": "", "haweis": "", "noyes": "The prophecy concerning Damascus. Behold, Damascus shall be no more a city; It shall become a heap of ruins.", "webster": "The burden of Damascus. Behold, Damascus is taken away from [being] a city, and it shall be a ruinous heap.", "vulgate": "onus Damasci ecce Damascus desinet esse civitas et erit sicut acervus lapidum in ruina;", "brenton": "THE WORD AGAINST DAMASCUS. Behold, Damascus shall be taken away from among cities, and shall become a ruin;"}}, {"v": 2, "ref": "17:2", "o": "עֲזֻב֖וֹת עָרֵ֣י עֲרֹעֵ֑ר לַ/עֲדָרִ֣ים תִּֽהְיֶ֔ינָה וְ/רָבְצ֖וּ וְ/אֵ֥ין מַחֲרִֽיד", "en": {"kjv": "The cities of Aroer are forsaken: they shall be for flocks, which shall lie down, and none shall make them afraid.", "web": "The cities of Aroer are forsaken. They will be for flocks, which shall lie down, and no one shall make them afraid.", "bsb": "The cities of Aroer are forsaken; they will be left to the flocks, which will lie down with no one to fear.", "asv": "The cities of Aroer are forsaken; they shall be for flocks, which shall lie down, and none shall make them afraid.", "ylt": "Forsaken are the cities of Aroer, For droves they are, and they have lain down, And there is none troubling.", "dra": "The cities of Aroer shall be left for flocks, and they shall rest there, and there shall be none to make them afraid.", "bbe": "Her towns are unpeopled for ever; there the flocks take their rest in peace, without fear.", "geneva": "The cities of Aroer shall be forsaken: they shall be for the flockes: for they shall lye there, and none shall make them afraide.", "wycliffe": "The forsakun citees of Aroer schulen be to flockis; and tho schulen reste there, and noon schal be that schal make aferd.", "rotherham": "Forsaken, are the desolate cities,—For flocks, shall they serve, Which shall lie down and have none to make them afraid.", "darby": "The cities of Aroer are forsaken: they shall be for flocks; and they shall lie down and there shall be none to make them afraid.", "twenty": "", "jps": "The cities of Aroer are forsaken; they shall be for flocks, which shall lie down, and none shall make them afraid.", "acv": "The cities of Aroer are forsaken. They shall be for flocks, which shall lie down, and none shall make them afraid.", "anderson": "", "haweis": "", "noyes": "The cities of Aroer shall be forsaken; They shall be pastures for flocks, Which shall lie down, and none shall make them afraid.", "webster": "The cities of Aroer [are] forsaken: they shall be for flocks, which shall lie down, and none shall make [them] afraid.", "vulgate": "derelictae civitates Aroer gregibus erunt et requiescent ibi et non erit qui exterreat;", "brenton": "abandoned for ever, to be a fold and resting-place for flocks, and there shall be none to go after them."}}, {"v": 3, "ref": "17:3", "o": "וְ/נִשְׁבַּ֤ת מִבְצָר֙ מֵֽ/אֶפְרַ֔יִם וּ/מַמְלָכָ֥ה מִ/דַּמֶּ֖שֶׂק וּ/שְׁאָ֣ר אֲרָ֑ם כִּ/כְב֤וֹד בְּנֵֽי יִשְׂרָאֵל֙ יִֽהְי֔וּ נְאֻ֖ם יְהוָ֥ה צְבָאֽוֹת", "en": {"kjv": "The fortress also shall cease from Ephraim, and the kingdom from Damascus, and the remnant of Syria: they shall be as the glory of the children of Israel, saith the Lord of hosts.", "web": "The fortress shall cease from Ephraim, and the kingdom from Damascus, and the remnant of Syria. They will be as the glory of the children of Israel,” says Yahweh of Armies.", "bsb": "The fortress will disappear from Ephraim, and the sovereignty from Damascus. The remnant of Aram will be like the splendor of the Israelites,” declares the LORD of Hosts.", "asv": "And the fortress shall cease from Ephraim, and the kingdom from Damascus, and the remnant of Syria; they shall be as the glory of the children of Israel, saith Jehovah of hosts.", "ylt": "And ceased hath the fortress from Ephraim, And the kingdom from Damascus, And the remnant of Aram are as the honour of the sons of Israel, The affirmation of Jehovah of Hosts!", "dra": "And aid shall cease from Ephraim, and the kingdom from Damascus: and the remnant of Syria shall be as the glory of the children of Israel: saith the Lord of hosts.", "bbe": "The strong tower has gone from Ephraim, and the kingdom from Damascus: the rest of Aram will come to destruction, and be made like the glory of the children of Israel, says the Lord of armies.", "geneva": "The munition also shall cease from Ephraim, and the kingdome from Damascus, and the remnant of Aram shall be as the glory of the children of Israel, sayeth the Lord of hostes.", "wycliffe": "And help schal ceesse fro Effraym, and a rewme fro Damask; and the relifs of Sirie schulen be as the glorie of the sones of Israel, seith the Lord of oostis.", "rotherham": "Then shall the fortress cease from Ephraim, And the kingdom from Damascus and the remnant of Syria,—Like the glory of the sons of Israel, shall they be,—Declareth Yahweh of hosts.", "darby": "The fortress also shall cease from Ephraim, and the kingdom from Damascus, and the remnant of Syria: they shall be as the glory of the children of Israel, saith Jehovah of hosts.", "twenty": "", "jps": "The fortress also shall cease from Ephraim, and the kingdom from Damascus; and the remnant of Aram shall be as the glory of the children of Israel, saith HaShem of hosts.", "acv": "And the fortress shall cease from Ephraim, and the kingdom from Damascus. And the remnant of Syria, they shall be as the glory of the sons of Israel, says Jehovah of hosts.", "anderson": "", "haweis": "", "noyes": "The fortress shall cease from Ephraim, And the kingdom from Damascus, and the rest of Syria; It shall be with them as with the glory of the children of Israel, Saith Jehovah of hosts.", "webster": "The fortress also shall cease from Ephraim, and the kingdom from Damascus, and the remnant of Syria: they shall be as the glory of the children of Israel, saith the LORD of hosts.", "vulgate": "et cessabit adiutorium ab Ephraim et regnum a Damasco et reliquiae Syriae sicut gloria filiorum Israhel erunt dicit Dominus exercituum;", "brenton": "And she shall no longer be a strong place for Ephraim to flee to, and there shall no longer be a kingdom in Damascus, or a remnant of Syrians; for thou art no better than the children of Israel, even than their glory; thus saith the Lord of hosts."}}, {"v": 4, "ref": "17:4", "o": "וְ/הָיָה֙ בַּ/יּ֣וֹם הַ/ה֔וּא יִדַּ֖ל כְּב֣וֹד יַעֲקֹ֑ב וּ/מִשְׁמַ֥ן בְּשָׂר֖/וֹ יֵרָזֶֽה", "en": {"kjv": "And in that day it shall come to pass, that the glory of Jacob shall be made thin, and the fatness of his flesh shall wax lean.", "web": "“It will happen in that day that the glory of Jacob will be made thin, and the fatness of his flesh will become lean.", "bsb": "“In that day the splendor of Jacob will fade, and the fat of his body will waste away,", "asv": "And it shall come to pass in that day, that the glory of Jacob shall be made thin, and the fatness of his flesh shall wax lean.", "ylt": "And it hath come to pass, in that day, Wax poor doth the honour of Jacob, And the fatness of his flesh doth wax lean.", "dra": "And it shall come to pass in that day, that the glory of Jacob shall be made thin, and the fatness of his flesh shall grow lean.", "bbe": "And it will be in that day that the glory of Jacob will be made small, and the strength of his body will become feeble.", "geneva": "And in that day the glorie of Iaakob shall be impouerished, and the fatnes of his flesh shalbe made leane.", "wycliffe": "And it schal be, in that dai the glorie of Jacob schal be maad thinne, and the fatnesse of his fleisch shal fade.", "rotherham": "And it shall come to pass in that day, That the glory of Jacob, shall be diminished, And, the fatness of his flesh, shall be wasted;", "darby": "And in that day it shall come to pass, that the glory of Jacob shall be made thin, and the fatness of his flesh shall become lean.", "twenty": "", "jps": "And it shall come to pass in that day, that the glory of Jacob shall be made thin, and the fatness of his flesh shall wax lean.", "acv": "And it shall come to pass in that day, that the glory of Jacob shall be made thin, and the fatness of his flesh shall grow lean.", "anderson": "", "haweis": "", "noyes": "In that day shall the glory of Jacob sink away, And the fatness of his flesh become leanness.", "webster": "And in that day it shall come to pass, [that] the glory of Jacob shall be diminished, and the fatness of his flesh shall become lean.", "vulgate": "et erit in die illa adtenuabitur gloria Iacob et pingue carnis eius marcescet;", "brenton": "There shall be in that day a failure of the glory of Jacob, and the riches of his glory shall be shaken."}}, {"v": 5, "ref": "17:5", "o": "וְ/הָיָ֗ה כֶּֽ/אֱסֹף֙ קָצִ֣יר קָמָ֔ה וּ/זְרֹע֖/וֹ שִׁבֳּלִ֣ים יִקְצ֑וֹר וְ/הָיָ֛ה כִּ/מְלַקֵּ֥ט שִׁבֳּלִ֖ים בְּ/עֵ֥מֶק רְפָאִֽים", "en": {"kjv": "And it shall be as when the harvestman gathereth the corn, and reapeth the ears with his arm; and it shall be as he that gathereth ears in the valley of Rephaim.", "web": "It will be like when the harvester gathers the wheat, and his arm reaps the grain. Yes, it will be like when one gleans grain in the valley of Rephaim.", "bsb": "as the reaper gathers the standing grain and harvests the ears with his arm, as one gleans heads of grain in the Valley of Rephaim.", "asv": "And it shall be as when the harvestman gathereth the standing grain, and his arm reapeth the ears; yea, it shall be as when one gleaneth ears in the valley of Rephaim.", "ylt": "And it hath come to pass, As the gathering by the reaper of the standing corn, And his arm the ears reapeth, And it hath come to pass, As the gathering of the ears in the valley of Rephaim,", "dra": "And it shall be as when one gathereth in the harvest that which remaineth, and his arm shall gather the ears of corn: and it shall be as he that seeketh ears in the vale of Raphaim.", "bbe": "And it will be like a man cutting the growth of his grain, pulling together the heads of the grain with his arm; even as when they get in the grain in the valley of Rephaim.", "geneva": "And it shalbe as when the haruest man gathereth the corne, and reapeth the eares with his arme, and he shall be as he that gathereth the eares in the valley of Rephaim.", "wycliffe": "And it schal be as gaderyng togidere that that is left in heruest, and his arm schal gadere eeris of corn, and it schal be as sekynge eeris of corn in the valei of Raphaym.", "rotherham": "And it shall come to pass—That, as the harvestman gathereth standing corn, And with his arm—the ears, he reapeth, Yea it shall come to pass—That, so, shall he be who gleaneth ears, in the vale of Rephaim;", "darby": "And it shall be as when the reaper gathereth the corn, and reapeth the ears with his arm; yea, it shall be as he that gathereth ears in the valley of Rephaim.", "twenty": "", "jps": "And it shall be as when the harvestman gathereth the standing corn, and reapeth the ears with his arm; yea, it shall be as when one gleaneth ears in the valley of Rephaim.", "acv": "And it shall be as when the harvestman gathers the standing grain, and his arm reaps the ears. Yea, it shall be as when he gleans ears in the valley of Rephaim.", "anderson": "", "haweis": "", "noyes": "And it shall be as when the harvest-man gathereth the corn, And reapeth the ears with his arm; Yea, as when one gleaneth ears in the valley of Rephaim.", "webster": "And it shall be as when the harvest-man gathereth the corn, and reapeth the ears with his arm; and it shall be as he that gathereth ears in the valley of Rephaim.", "vulgate": "et erit sicut congregans in messe quod restiterit et brachium eius spicas leget et erit sicut quaerens spicas in valle Rafaim;", "brenton": "And it shall be as if one should gather standing corn, and reap the grain of the ears; and it shall be as if one should gather ears in a rich valley;"}}, {"v": 6, "ref": "17:6", "o": "וְ/נִשְׁאַר בּ֤/וֹ עֽוֹלֵלֹת֙ כְּ/נֹ֣קֶף זַ֔יִת שְׁנַ֧יִם שְׁלֹשָׁ֛ה גַּרְגְּרִ֖ים בְּ/רֹ֣אשׁ אָמִ֑יר אַרְבָּעָ֣ה חֲמִשָּׁ֗ה בִּ/סְעִפֶ֨י/הָ֙ פֹּֽרִיָּ֔ה נְאֻם יְהוָ֖ה אֱלֹהֵ֥י יִשְׂרָאֵֽל", "en": {"kjv": "Yet gleaning grapes shall be left in it, as the shaking of an olive tree, two or three berries in the top of the uppermost bough, four or five in the outmost fruitful branches thereof, saith the Lord God of Israel.", "web": "Yet gleanings will be left there, like the shaking of an olive tree, two or three olives in the top of the uppermost bough, four or five in the outermost branches of a fruitful tree,” says Yahweh, the God of Israel.", "bsb": "Yet gleanings will remain, like an olive tree that has been beaten— two or three berries atop the tree, four or five on its fruitful branches,” declares the LORD, the God of Israel.", "asv": "Yet there shall be left therein gleanings, as the shaking of an olive-tree, two or three berries in the top of the uppermost bough, four or five in the outmost branches of a fruitful tree, saith Jehovah, the God of Israel.", "ylt": "And left in him have been gleanings, As the compassing of an olive, Two--three berries on the top of a branch, Four--five on the fruitful boughs, The affirmation of Jehovah, God of Israel!", "dra": "And the fruit thereof that shall be left upon it, shall be as one cluster of grapes, and as the shaking of the olive tree, two or three berries in the top of a bough, or four or five upon the top of the tree, saith the Lord the God of Israel.", "bbe": "But it will be like a man shaking an olive-tree, something will still be there, two or three berries on the top of the highest branch, four or five on the outside branches of a fertile tree, says the Lord, the God of Israel.", "geneva": "Yet a gathering of grapes shall be left in it, as the shaking of an oliue tree, two or three beries are in the top of the vpmost boughes, and foure or fiue in the hie branches of the fruite thereof, sayeth the Lord God of Israel.", "wycliffe": "And there schal be left in it as a rasyn, and as the schakyng doun of the fruyt of olyue tre, as of tweyne ether of thre olyue trees in the hiynesse of a braunche, ether of foure ether of fyue; in the cooppis therof schal be the fruyt therof, seith the Lord God of Israel.", "rotherham": "Yet shall there be left therein, a gleaning. As in the beating of an olive-tree,—Two-three berries in the head of the tree-top,—Four—five, among her fruitful boughs, Declareth Yahweh God of Israel.", "darby": "And a gleaning shall be left in it, as at the shaking of an olive-tree: two, three berries above, in the tree-top; four, five in its fruitful boughs, saith Jehovah, theGod of Israel.", "twenty": "", "jps": "Yet there shall be left therein gleanings, as at the beating of an olive-tree, two or three berries in the top of the uppermost bough, four or five in the branches of the fruitful tree, saith HaShem, the G-d of Israel.", "acv": "Yet there shall be gleanings left in it, as the shaking of an olive tree-two or three berries in the top of the uppermost bough, four or five in the outmost branches of a fruitful tree, says Jehovah, the God of Israel.", "anderson": "", "haweis": "", "noyes": "There shall be left in it only a gleaning, as in the olive-harvest, Two or three berries on the top of the highest bough, Four or five on the fruitful branches, Saith Jehovah, the God of Israel.", "webster": "Yet gleaning grapes shall be left in it, as the shaking of an olive-tree, two [or] three berries in the top of the uppermost bough, four [or] five in the outmost fruitful branches of it, saith the LORD God of Israel.", "vulgate": "et relinquetur in eo sicut racemus et sicut excussio oleae duarum aut trium olivarum in summitate rami sive quattuor aut quinque in cacuminibus eius fructus eius dicit Dominus Deus Israhel;", "brenton": "and as if there should be left stubble therein, or as it were the berries of an olive tree, two or three on the topmost bough, or as if four or five should be left on their branches; thus saith the Lord, the God of Israel."}}, {"v": 7, "ref": "17:7", "o": "בַּ/יּ֣וֹם הַ/ה֔וּא יִשְׁעֶ֥ה הָ/אָדָ֖ם עַל עֹשֵׂ֑/הוּ וְ/עֵינָ֕י/ו אֶל קְד֥וֹשׁ יִשְׂרָאֵ֖ל תִּרְאֶֽינָה", "en": {"kjv": "At that day shall a man look to his Maker, and his eyes shall have respect to the Holy One of Israel.", "web": "In that day, people will look to their Maker, and their eyes will have respect for the Holy One of Israel.", "bsb": "In that day men will look to their Maker and turn their eyes to the Holy One of Israel.", "asv": "In that day shall men look unto their Maker, and their eyes shall have respect to the Holy One of Israel.", "ylt": "In that day doth man look to His Maker, Yea, his eyes to the Holy One of Israel look,", "dra": "In that day man shall bow down himself to his Maker, and his eyes shall look to the Holy One of Israel.", "bbe": "In that day a man's heart will be turned to his Maker, and his eyes to the Holy One of Israel.", "geneva": "At that day shall a man looke to his maker, and his eyes shall looke to the holy one of Israel.", "wycliffe": "In that dai a man schal be bowid to his maker, and hise iyen schulen biholde to the hooli of Israel.", "rotherham": "In that day, shall the son of earth look to him that made him,—And his eyes unto the Holy One of Israel, be turned;", "darby": "In that day shall man look to his Maker, and his eyes shall have regard to the Holy One of Israel.", "twenty": "", "jps": "In that day shall a man regard his Maker, and his eyes shall look to the Holy One of Israel.", "acv": "In that day men shall look to their maker, and their eyes shall have respect for the Holy One of Israel.", "anderson": "", "haweis": "", "noyes": "In that day shall a man have regard to his Maker, And his eyes shall look to the Holy One of Israel.", "webster": "At that day shall a man look to his Maker, and his eyes shall have respect to the Holy One of Israel.", "vulgate": "in die illa inclinabitur homo ad factorem suum et oculi eius ad Sanctum Israhel respicient;", "brenton": "In that day a man shall trust in him that made him, and his eyes shall have respect to the Holy One of Israel."}}, {"v": 8, "ref": "17:8", "o": "וְ/לֹ֣א יִשְׁעֶ֔ה אֶל הַֽ/מִּזְבְּח֖וֹת מַעֲשֵׂ֣ה יָדָ֑י/ו וַ/אֲשֶׁ֨ר עָשׂ֤וּ אֶצְבְּעֹתָי/ו֙ לֹ֣א יִרְאֶ֔ה וְ/הָ/אֲשֵׁרִ֖ים וְ/הָ/חַמָּנִֽים", "en": {"kjv": "And he shall not look to the altars, the work of his hands, neither shall respect that which his fingers have made, either the groves, or the images.", "web": "They will not look to the altars, the work of their hands; neither shall they respect that which their fingers have made, either the Asherah poles, or the incense altars.", "bsb": "They will not look to the altars they have fashioned with their hands or to the Asherahs and incense altars they have made with their fingers.", "asv": "And they shall not look to the altars, the work of their hands; neither shall they have respect to that which their fingers have made, either the Asherim, or the sun-images.", "ylt": "And he looketh not unto the altars. The work of his own hands, And that which his own fingers made He seeth not--the shrines and the images.", "dra": "And he shall not look to the altars which his hands made; and he shall not have respect to the things that his fingers wrought, such as groves and temples.", "bbe": "He will not be looking to the altars, the work of his hands, or to the wood pillars or to the sun-images which his fingers have made.", "geneva": "And hee shall not looke to the altars, the workes of his owne hands, neither shall he looke to those thinges, which his owne fingers haue made, as groues and images.", "wycliffe": "And he schal not be bowid to the auteris, whiche hise hondis maden, and whiche hise fyngris wrouyten; he schal not biholde wodis, and templis of idols.", "rotherham": "And he shall not look unto the altars the work of his own hands,—Nor to what his own fingers have made, shall his eye be turned, Whether Sacred Stems or Sun-pillars.", "darby": "And he will not look to the altars, the work of his hands, nor have regard to what his fingers have made, neither the Asherahs nor the sun-images.", "twenty": "", "jps": "And he shall not regard the altars, the work of his hands, neither shall he look to that which his fingers have made, either the Asherim, or the sun-images.", "acv": "And they shall not look to the altars, the work of their hands, nor shall they have respect for that which their fingers have made, either the Asherim, or the sun-images.", "anderson": "", "haweis": "", "noyes": "He shall not look to the altars, the work of his hands, Nor have respect to that which his fingers have made, The images of Astarte and the Sun-pillars.", "webster": "And he shall not look to the altars, the work of his hands, neither shall respect [that] which his fingers have made, either the groves, or the images.", "vulgate": "et non inclinabitur ad altaria quae fecerunt manus eius et quae operati sunt digiti eius non respiciet lucos et delubra;", "brenton": "And they shall not at all trust in their altars, nor in the works of their hands, which their fingers made; and they shall not look to the trees, nor to their abominations."}}, {"v": 9, "ref": "17:9", "o": "בַּ/יּ֨וֹם הַ/ה֜וּא יִהְי֣וּ עָרֵ֣י מָעֻזּ֗/וֹ כַּ/עֲזוּבַ֤ת הַ/חֹ֨רֶשׁ֙ וְ/הָ֣/אָמִ֔יר אֲשֶׁ֣ר עָזְב֔וּ מִ/פְּנֵ֖י בְּנֵ֣י יִשְׂרָאֵ֑ל וְ/הָיְתָ֖ה שְׁמָמָֽה", "en": {"kjv": "In that day shall his strong cities be as a forsaken bough, and an uppermost branch, which they left because of the children of Israel: and there shall be desolation.", "web": "In that day, their strong cities will be like the forsaken places in the woods and on the mountain top, which were forsaken from before the children of Israel; and it will be a desolation.", "bsb": "In that day their strong cities will be like forsaken thickets and summits, abandoned to the Israelites and to utter desolation.", "asv": "In that day shall their strong cities be as the forsaken places in the wood and on the mountain top, which were forsaken from before the children of Israel; and it shall be a desolation.", "ylt": "In that day are the cities of his strength As the forsaken thing of the forest, And the branch that they have left, Because of the sons of Israel, It also hath been a desolation.", "dra": "In that day his strong cities shall be forsaken, as the ploughs, and the corn that were left before the face of the children of Israel, and thou shalt be desolate.", "bbe": "In that day your towns will be like the waste places of the Hivites and the Amorites which the children of Israel took for a heritage, and they will come to destruction.", "geneva": "In that day shall the cities of their strength be as the forsaking of boughes and branches, which they did forsake, because of the children of Israel, and there shall be desolation.", "wycliffe": "In that dai the citees of strengthe therof schulen be forsakun as plowis, and cornes that weren forsakun of the face of the sones of Israel; and thou schalt be forsakun.", "rotherham": "In that day, shall his fortified cities become Like a neglected bough and a topmost branch, Which they neglected because of the sons of Israel,—So shall there be desolation.", "darby": "In that day shall his strong cities be as the forsaken tract in the woodland, and the mountain-top which they forsook before the children of Israel; and there shall be desolation.", "twenty": "", "jps": "In that day shall his strong cities be as the forsaken places, which were forsaken from before the children of Israel, after the manner of woods and lofty forests; and it shall be a desolation.", "acv": "In that day their strong cities shall be as the forsaken places in the woodland and on the mountain top, which were forsaken from before the sons of Israel, and it shall be a desolation.", "anderson": "", "haweis": "", "noyes": "In that day shall his fortified cities be like ruins in the forests, or on the mountain tops, Which the enemy left, in flight from the children of Israel; And the land shall be a desolation.", "webster": "In that day shall his strong cities be as a forsaken bough, and an uppermost branch, which they left because of the children of Israel: and there shall be desolation.", "vulgate": "in die illa erunt civitates fortitudinis eius derelictae sicut aratra et segetes quae derelictae sunt a facie filiorum Israhel et erit deserta;", "brenton": "In that day thy cities shall be deserted, as the Amorites and the Evaeans deserted theirs, because of the children of Israel; and they shall be desolate."}}, {"v": 10, "ref": "17:10", "o": "כִּ֤י שָׁכַ֨חַתְּ֙ אֱלֹהֵ֣י יִשְׁעֵ֔/ךְ וְ/צ֥וּר מָעֻזֵּ֖/ךְ לֹ֣א זָכָ֑רְתְּ עַל כֵּ֗ן תִּטְּעִי֙ נִטְעֵ֣י נַעֲמָנִ֔ים וּ/זְמֹ֥רַת זָ֖ר תִּזְרָעֶֽ/נּוּ", "en": {"kjv": "Because thou hast forgotten the God of thy salvation, and hast not been mindful of the rock of thy strength, therefore shalt thou plant pleasant plants, and shalt set it with strange slips:", "web": "For you have forgotten the God of your salvation, and have not remembered the rock of your strength. Therefore you plant pleasant plants, and set out foreign seedlings.", "bsb": "For you have forgotten the God of your salvation and failed to remember the Rock of your refuge. Therefore, though you cultivate delightful plots and set out cuttings from exotic vines—", "asv": "For thou hast forgotten the God of thy salvation, and hast not been mindful of the rock of thy strength; therefore thou plantest pleasant plants, and settest it with strange slips.", "ylt": "Because thou hast forgotten the God of thy salvation, And the rock of thy strength hast not remembered, Therefore thou plantest plants of pleasantness, And with a strange slip sowest it,", "dra": "Because thou hast forgotten God thy saviour, and hast not remembered thy strong helper: therefore shalt thou plant good plants, and shalt sow strange seed.", "bbe": "For you have not given honour to the God of your salvation, and have not kept in mind the Rock of your strength; for this cause you made a garden of Adonis, and put in it the vine-cuttings of a strange god;", "geneva": "Because thou hast forgotten the God of thy saluation, and hast not remembred the God of thy strength, therefore shalt thou set pleasant plantes, and shalt graffe strange vine branches:", "wycliffe": "For thou hast foryete God, thi sauyour, and haddist not mynde on thi stronge helpere; therfor thou schalt plaunte a feithful plauntyng, and thou schalt sowe an alien seed.", "rotherham": "Because thou didst forget the God of thy salvation, And thy Rock of refuge, thou didst not remember, For this cause, shalt thou plant very pleasant plants, And, the slip of a stranger, shalt thou set:", "darby": "For thou hast forgotten theGod of thy salvation, and hast not been mindful of the rock of thy strength; therefore shalt thou plant pleasant plantations, and shalt set them with foreign slips:", "twenty": "", "jps": "For thou hast forgotten the G-d of thy salvation, and thou hast not been mindful of the Rock of thy stronghold; therefore thou didst plant plants of pleasantness, and didst set it with slips of a stranger;", "acv": "For thou have forgotten the God of thy salvation, and have not been mindful of the rock of thy strength. Therefore thou plant pleasant plants, and set it with foreign slips.", "anderson": "", "haweis": "", "noyes": "For thou hast forgotten the God of thy salvation, And hast not been mindful of the rock of thy strength; Therefore though thou plant beautiful plants, And set shoots from a foreign soil,", "webster": "Because thou hast forgotten the God of thy salvation, and hast not been mindful of the rock of thy strength, therefore shalt thou plant pleasant plants, and shalt set it with foreign slips:", "vulgate": "quia oblita es Dei salvatoris tui et Fortis adiutoris tui non es recordata propterea plantabis plantationem fidelem et germen alienum seminabis;", "brenton": "Because thou hast forsaken God thy Saviour, and hast not been mindful of the Lord thy helper; therefore shalt thou plant a false plant, and a false seed."}}, {"v": 11, "ref": "17:11", "o": "בְּ/י֤וֹם נִטְעֵ/ךְ֙ תְּשַׂגְשֵׂ֔גִי וּ/בַ/בֹּ֖קֶר זַרְעֵ֣/ךְ תַּפְרִ֑יחִי נֵ֥ד קָצִ֛יר בְּ/י֥וֹם נַחֲלָ֖ה וּ/כְאֵ֥ב אָנֽוּשׁ", "en": {"kjv": "In the day shalt thou make thy plant to grow, and in the morning shalt thou make thy seed to flourish: but the harvest shall be a heap in the day of grief and of desperate sorrow.", "web": "In the day of your planting, you hedge it in. In the morning, you make your seed blossom, but the harvest flees away in the day of grief and of desperate sorrow.", "bsb": "though on the day you plant you make them grow, and on that morning you help your seed sprout— yet the harvest will vanish on the day of disease and incurable pain.", "asv": "In the day of thy planting thou hedgest it in, and in the morning thou makest thy seed to blossom; but the harvest fleeth away in the day of grief and of desperate sorrow.", "ylt": "In the day thy plant thou causest to become great, And in the morning thy seed makest to flourish, A heap is the harvest in a day of overflowing, And of mortal pain.", "dra": "In the day of thy planting shall be the wild grape, and in the morning thy seed shall flourish: the harvest is taken away in the day of inheritance, and shall grieve thee much.", "bbe": "In the day of your planting you were watching its growth, and in the morning your seed was flowering: but its fruit is wasted away in the day of grief and bitter sorrow.", "geneva": "In the day shalt thou make thy plant to growe, and in the morning shalt thou make thy seede to florish: but the haruest shall be gone in the day of possession, and there shalbe desperate sorrowe.", "wycliffe": "In the dai of thi plauntyng schal be a wielde vyne, and erli thi seed schal floure; ripe corne is takun awei in the dai of eritage, and Israel schal make sorewe greuousli.", "rotherham": "In the day when thou plantest, fence thou in, And in the morning, cause thou, thy slip, to blossom,—A harvest will have waved in the day of destiny, and mortal pain.", "darby": "in the day of thy planting wilt thou make [them] to grow, and on the morrow wilt thou make thy seed to flourish; [but] the harvest will flee in the day of taking possession, and the sorrow will be incurable.", "twenty": "", "jps": "In the day of thy planting thou didst make it to grow, and in the morning thou didst make thy seed to blossom--a heap of boughs in the day of grief and of desperate pain.", "acv": "In the day of thy planting thou hedge it in, and in the morning thou make thy seed to blossom. But the harvest flees away in the day of grief and of desperate sorrow.", "anderson": "", "haweis": "", "noyes": "When thou hast planted them, though thou hedge them in, And in the morning bring thy plants to the blossom, Yet shall the harvest flee away, In the day of pain and desperate sorrow.", "webster": "In the day shalt thou make thy plant to grow, and in the morning shalt thou make thy seed to flourish: [but] the harvest [shall be] a heap in the day of grief and of desperate sorrow.", "vulgate": "in die plantationis tuae labrusca et mane semen tuum florebit ablata est messis in die hereditatis et dolebit graviter;", "brenton": "In the day wherein thou shalt plant thou shalt be deceived; but if thou sow in the morning, the seed shall spring up for a crop in the day wherein thou shalt obtain an inheritance, and as a man's father, thou shalt obtain an inheritance for thy sons."}}, {"v": 12, "ref": "17:12", "o": "ה֗וֹי הֲמוֹן֙ עַמִּ֣ים רַבִּ֔ים כַּ/הֲמ֥וֹת יַמִּ֖ים יֶהֱמָי֑וּ/ן וּ/שְׁא֣וֹן לְאֻמִּ֔ים כִּ/שְׁא֛וֹן מַ֥יִם כַּבִּירִ֖ים יִשָּׁאֽוּ/ן", "en": {"kjv": "Woe to the multitude of many people, which make a noise like the noise of the seas; and to the rushing of nations, that make a rushing like the rushing of mighty waters!", "web": "Ah, the uproar of many peoples, who roar like the roaring of the seas; and the rushing of nations, that rush like the rushing of mighty waters!", "bsb": "Alas, the tumult of many peoples; they rage like the roaring seas and clamoring nations; they rumble like the crashing of mighty waters.", "asv": "Ah, the uproar of many peoples, that roar like the roaring of the seas; and the rushing of nations, that rush like the rushing of mighty waters!", "ylt": "Woe to the multitude of many peoples, As the sounding of seas they sound; And to the wasting of nations, As the wasting of mighty waters they are wasted.", "dra": "Woe to the multitude of many people, like the multitude of the roaring sea: and the tumult of crowds, like the noise of many waters.", "bbe": "Ah! the voice of peoples, like the loud sounding of the seas, and the thundering of great nations rushing on like the bursting out of waters!", "geneva": "Ah, the multitude of many people, they shall make a sounde like the noyse of the sea: for the noyse of the people shall make a sounde like the noyse of mightie waters.", "wycliffe": "Wo to the multitude of many puplis, as the multitude of the see sownynge, and the noise of cumpenyes as the sown of many watris.", "rotherham": "Alas! the booming of many peoples, Like the booming of the seas, shall they boom,—And the rushing of nations! Like the rushing of mighty waters, shall they rush.", "darby": "Ha! a tumult of many peoples! they make a noise as the noise of the seas; — and the rushing of nations! they rush as the rushing of mighty waters.", "twenty": "", "jps": "Ah, the uproar of many peoples, that roar like the roaring of the seas; and the rushing of nations, that rush like the rushing of mighty waters!", "acv": "Ah, the uproar of many peoples, who roar like the roaring of the seas, and the rushing of nations, that rush like the rushing of mighty waters!", "anderson": "", "haweis": "", "noyes": "Alas! a tumult of many nations! They rage with the raging of the sea. Alas! a roaring of kingdoms! They roar with the roaring of mighty waters.", "webster": "Woe to the multitude of many people, [who] make a noise like the noise of the seas; and to the rushing of nations, [that] make a rushing like the rushing of mighty waters!", "vulgate": "vae multitudo populorum multorum ut multitudo maris sonantis et tumultus turbarum sicut sonitus aquarum multarum;", "brenton": "Woe to the multitude of many nations, as the swelling sea, so shall ye be confounded; and the force of many nations shall sound like water;"}}, {"v": 13, "ref": "17:13", "o": "לְאֻמִּ֗ים כִּ/שְׁא֞וֹן מַ֤יִם רַבִּים֙ יִשָּׁא֔וּ/ן וְ/גָ֥עַר בּ֖/וֹ וְ/נָ֣ס מִ/מֶּרְחָ֑ק וְ/רֻדַּ֗ף כְּ/מֹ֤ץ הָרִים֙ לִ/פְנֵי ר֔וּחַ וּ/כְ/גַלְגַּ֖ל לִ/פְנֵ֥י סוּפָֽה", "en": {"kjv": "The nations shall rush like the rushing of many waters: but God shall rebuke them, and they shall flee far off, and shall be chased as the chaff of the mountains before the wind, and like a rolling thing before the whirlwind.", "web": "The nations will rush like the rushing of many waters: but he will rebuke them, and they will flee far off, and will be chased like the chaff of the mountains before the wind, and like the whirling dust before the storm.", "bsb": "The nations rage like the rush of many waters. He rebukes them, and they flee far away, driven before the wind like chaff on the hills, like tumbleweeds before a gale.", "asv": "The nations shall rush like the rushing of many waters: but he shall rebuke them, and they shall flee far off, and shall be chased as the chaff of the mountains before the wind, and like the whirling dust before the storm.", "ylt": "Nations as the wasting of many waters are wasted, And He hath pushed against it, And it hath fled afar off, And been pursued as chaff of hills before wind, And as a rolling thing before a hurricane.", "dra": "Nations shall make a noise like the noise of waters overflowing, but he shall rebuke him, and he shall flee far off: and he shall be carried away as the dust of the mountains before the wind, and as a whirlwind before a tempest.", "bbe": "But he will put a stop to them, and make them go in flight far away, driving them like the waste of the grain on the tops of the mountains before the wind, and like the circling dust before the storm.", "geneva": "The people shall make a sounde like the noise of many waters: but God shall rebuke them, and they shall flee farre off, and shalbe chased as the chaffe of the mountaines before the winde, and as a rolling thing before the whirlewinde.", "wycliffe": "Puplis schulen sowne as the sown of flowynge watris, and God schal blame hym; and he schal fle fer, and he schal be rauyschid as the dust of hillis fro the face of the wynd, and as a whirlewynd bifor tempest.", "rotherham": "Though nations like the rushing of many waters, shall rush, Yet shall one rebuke him, And he shall flee far away,—And be chased As the chaff of the mountains before a wind, And as whirling stubble before a storm!", "darby": "The nations rush as the rushing of many waters; but he will rebuke them, and they shall flee far away, and shall be chased as the chaff of the mountains before the wind, and like a whirling [of dust] before the whirlwind:", "twenty": "", "jps": "The nations shall rush like the rushing of many waters; but He shall rebuke them, and they shall flee far off, and shall be chased as the chaff of the mountains before the wind, and like the whirling dust before the storm.", "acv": "The nations shall rush like the rushing of many waters, but he shall rebuke them. And they shall flee far off, and shall be chased as the chaff of the mountains before the wind, and like the whirling dust before the storm.", "anderson": "", "haweis": "", "noyes": "Like the roaring of mighty waters do the nations roar; He rebuketh them, and they flee away, Driven like the chaff of the mountains before the wind, Like stubble before the whirlwind.", "webster": "The nations shall rush like the rushing of many waters: but [God] will rebuke them, and they shall flee far off, and shall be chased as the chaff of the mountains before the wind, and like a rolling thing before the whirlwind.", "vulgate": "sonabunt populi sicut sonitus aquarum inundantium et increpabit eum et fugiet procul et rapietur sicut pulvis montium a facie venti et sicut turbo coram tempestate;", "brenton": "many nations like much water, as when much water rushes violently: and they shall drive him away, and pursue him afar, as the dust of chaff when men winnow before the wind, and as a storm whirling the dust of the wheel."}}, {"v": 14, "ref": "17:14", "o": "לְ/עֵ֥ת עֶ֨רֶב֙ וְ/הִנֵּ֣ה בַלָּהָ֔ה בְּ/טֶ֥רֶם בֹּ֖קֶר אֵינֶ֑/נּוּ זֶ֚ה חֵ֣לֶק שׁוֹסֵ֔י/נוּ וְ/גוֹרָ֖ל לְ/בֹזְזֵֽי/נוּ", "en": {"kjv": "And behold at eveningtide trouble; and before the morning he is not. This is the portion of them that spoil us, and the lot of them that rob us.", "web": "At evening, behold, terror! Before the morning, they are no more. This is the portion of those who plunder us, and the lot of those who rob us.", "bsb": "In the evening, there is sudden terror! Before morning, they are no more! This is the portion of those who loot us and the lot of those who plunder us.", "asv": "At eventide, behold, terror; and before the morning they are not. This is the portion of them that despoil us, and the lot of them that rob us.", "ylt": "At even-time, lo, terror, before morning it is not, This is the portion of our spoilers, And the lot of our plunderers!", "dra": "In the time of the evening, behold there shall be trouble: the morning shall come, and he shall not be: this is the portion of them that have wasted us, and the lot of them that spoiled us.", "bbe": "In the evening there is fear, and in the morning they are gone. This is the fate of those who take our goods, and the reward of those who violently take our property for themselves.", "geneva": "And loe, in the euening there is trouble: but afore the morning it is gone. This is the portion of them that spoyle vs, and the lot of them that robbe vs.", "wycliffe": "In the time of euentide, and lo! disturbling; in the morewtid, and he schal not abide. This is the part of hem that destrieden vs, and the part of hem that rauyschiden vs.", "rotherham": "At eventide, lo! terror, Before morning, he is not! This, is the portion of them who plunder us, And the lot of them who make of us a prey.", "darby": "behold, at eventide, trouble; before the morning they are not. This is the portion of them that spoil us, and the lot of them that rob us.", "twenty": "", "jps": "At eventide behold terror; and before the morning they are not. This is the portion of them that spoil us, and the lot of them that rob us.", "acv": "At eventide, behold, terror, and before the morning they are not. This is the portion of those who despoil us, and the lot of those who rob us.", "anderson": "", "haweis": "", "noyes": "At the time of evening, behold, terror! Before morning, behold, they are no more! This is the portion of them that spoil us, And the lot of them that plunder us.", "webster": "And behold at the time of evening trouble; [and] before the morning he [is] not. This [is] the portion of them that ravage us, and the lot of them that rob us.", "vulgate": "in tempore vespere et ecce turbatio in matutino et non subsistet haec est pars eorum qui vastaverunt nos et sors diripientium nos;", "brenton": "Toward evening, and there shall be grief; before the morning, and he shall not be. This is the portion of them that spoiled you, and the inheritance to them that robbed you of your inheritance."}}]}, {"c": 18, "verses": [{"v": 1, "ref": "18:1", "o": "ה֥וֹי אֶ֖רֶץ צִלְצַ֣ל כְּנָפָ֑יִם אֲשֶׁ֥ר מֵ/עֵ֖בֶר לְ/נַֽהֲרֵי כֽוּשׁ", "en": {"kjv": "Woe to the land shadowing with wings, which is beyond the rivers of Ethiopia:", "web": "Ah, the land of the rustling of wings, which is beyond the rivers of Ethiopia;", "bsb": "Woe to the land of whirring wings, along the rivers of Cush,", "asv": "Ah, the land of the rustling of wings, which is beyond the rivers of Ethiopia;", "ylt": "Ho, land shadowed with wings, That is beyond the rivers of Cush,", "dra": "Woe to the land, the winged cymbal, which is beyond the rivers of Ethiopia,", "bbe": "Ho! land of the sounding of wings, on the other side of the rivers of Ethiopia:", "geneva": "Oh, the lande shadowing with winges, which is beyond the riuers of Ethiopia,", "wycliffe": "Wo to the lond, the cymbal of wyngis, which is biyende the flood of Ethiopie; that sendith messangeris bi the see,", "rotherham": "Ho! thou land of the buzzing of wings,—Which is beyond the rivers of Ethiopia:", "darby": "Ha! land shadowing with wings, which art beyond the rivers of Cush,", "twenty": "", "jps": "Ah, land of the buzzing of wings, which is beyond the rivers of Ethiopia;", "acv": "Ah, the land of the rustling of wings, which is beyond the rivers of Ethiopia,", "anderson": "", "haweis": "", "noyes": "Ho! thou land of rustling wings, Beyond the rivers of Ethiopia!", "webster": "Woe to the land shadowing with wings, which [is] beyond the rivers of Cush:", "vulgate": "vae terrae cymbalo alarum quae est trans flumina Aethiopiae;", "brenton": "Woe to you, ye wings of the land of ships, beyond the rivers of Ethiopia."}}, {"v": 2, "ref": "18:2", "o": "הַ/שֹּׁלֵ֨חַ בַּ/יָּ֜ם צִירִ֗ים וּ/בִ/כְלֵי גֹמֶא֮ עַל פְּנֵי מַיִם֒ לְכ֣וּ מַלְאָכִ֣ים קַלִּ֗ים אֶל גּוֹי֙ מְמֻשָּׁ֣ךְ וּ/מוֹרָ֔ט אֶל עַ֥ם נוֹרָ֖א מִן ה֣וּא וָ/הָ֑לְאָה גּ֚וֹי קַו קָ֣ו וּ/מְבוּסָ֔ה אֲשֶׁר בָּזְא֥וּ נְהָרִ֖ים אַרְצֽ/וֹ", "en": {"kjv": "That sendeth ambassadors by the sea, even in vessels of bulrushes upon the waters, saying, Go, ye swift messengers, to a nation scattered and peeled, to a people terrible from their beginning hitherto; a nation meted out and trodden down, whose land the rivers have spoiled!", "web": "that sends ambassadors by the sea, even in vessels of papyrus on the waters, saying, “Go, you swift messengers, to a nation tall and smooth, to a people awesome from their beginning onward, a nation that measures out and treads down, whose land the rivers divide!”", "bsb": "which sends couriers by sea, in papyrus vessels on the waters. Go, swift messengers, to a people tall and smooth-skinned, to a people widely feared, to a powerful nation of strange speech, whose land is divided by rivers.", "asv": "that sendeth ambassadors by the sea, even in vessels of papyrus upon the waters, saying, Go, ye swift messengers, to a nation tall and smooth, to a people terrible from their beginning onward, a nation that meteth out and treadeth down, whose land the rivers divide!", "ylt": "That is sending by sea ambassadors, Even with implements of reed on the face of the waters, --Go, ye light messengers, Unto a nation drawn out and peeled, Unto a people fearful from its beginning and onwards, A nation meeting out by line, and treading down, Whose land floods have spoiled.", "dra": "That sendeth ambassadors by the sea, and in vessels of bulrushes upon the waters. Go, ye swift angels, to a nation rent and torn in pieces: to a terrible people, after which there is no other: to a nation expecting and trodden underfoot, whose land the rivers have spoiled.", "bbe": "Which sends its representatives by the sea, even in ships of papyrus on the waters. Go back quickly, O representatives, to a nation tall and smooth, to a people causing fear through all their history; a strong nation, crushing down its haters, whose land is cut through by rivers.", "geneva": "Sending ambassadours by the Sea, euen in vessels of reedes vpon the waters, saying, Go, ye swift messengers, to a nation that is scattered abroade, and spoyled, vnto a terrible people from their beginning euen hitherto: a nation by litle and litle, euen troden vnder foote, whose land the floods haue spoyled.", "wycliffe": "and in vessels of papirus on watris. Go, ye messangeris, to the folk drawun up and to-rent; to a ferdful puple, aftir which is noon other; to the folk abidynge and defoulid, whos lond the flodis han rauyschid; to the hil of the name of the Lord of oostis, to the hil of Sion.", "rotherham": "That sendeth by the sea, ambassadors Even in vessels of paper-reed, upon the face of the waters,—Go ye swift messengers Unto a nation drawn out and polished, Unto a people terrible from their beginning and onwards,—A nation most mighty and subduing, Whose land rivers have cut through.", "darby": "that sendest ambassadors over the sea, and in vessels of papyrus upon the waters, [saying,] Go, swift messengers, to a nation scattered and ravaged, to a people terrible from their existence and thenceforth; to a nation of continued waiting and of treading down, whose land the rivers have spoiled!", "twenty": "", "jps": "That sendeth ambassadors by the sea, even in vessels of papyrus upon the waters! Go, ye swift messengers, to a nation tall and of glossy skin, to a people terrible from their beginning onward; a nation that is sturdy and treadeth down, whose land the rivers divide!", "acv": "that sends ambassadors by the sea, even in vessels of papyrus upon the waters, saying, Go, ye swift messengers, to a nation tall and smooth, to a people fearful from their beginning onward, a nation that metes out and treads down, whose land the rivers divide!", "anderson": "", "haweis": "", "noyes": "That sendest thy messengers upon the sea, In reed-boats upon the face of the waters: Go, ye swift messengers, to a nation tall and fair, To a people terrible from the first and onward, To a mighty, victorious people, Whose land is divided by rivers!", "webster": "That sendeth embassadors by the sea, even in vessels of bulrushes upon the waters, [saying], Go, ye swift messengers to a nation scattered and peeled, to a people terrible from their beginning hitherto; a nation measured by line and trodden down, whose land the rivers have laid waste.", "vulgate": "qui mittit in mari legatos et in vasis papyri super aquas ite angeli veloces ad gentem convulsam et dilaceratam ad populum terribilem post quem non est alius gentem expectantem expectantem et conculcatam cuius diripuerunt flumina terram eius;", "brenton": "He sends messengers by the sea, and paper letters on the water: for swift messengers shall go to a lofty nation, and to a strange and harsh people. Who is beyond it? a nation not looked for, and trodden down."}}, {"v": 3, "ref": "18:3", "o": "כָּל יֹשְׁבֵ֥י תֵבֵ֖ל וְ/שֹׁ֣כְנֵי אָ֑רֶץ כִּ/נְשֹׂא נֵ֤ס הָרִים֙ תִּרְא֔וּ וְ/כִ/תְקֹ֥עַ שׁוֹפָ֖ר תִּשְׁמָֽעוּ", "en": {"kjv": "All ye inhabitants of the world, and dwellers on the earth, see ye, when he lifteth up an ensign on the mountains; and when he bloweth a trumpet, hear ye.", "web": "All you inhabitants of the world, and you dwellers on the earth, when a banner is lifted up on the mountains, look! When the trumpet is blown, listen!", "bsb": "All you people of the world and dwellers of the earth, when a banner is raised on the mountains, you will see it; when a ram’s horn sounds, you will hear it.", "asv": "All ye inhabitants of the world, and ye dwellers on the earth, when an ensign is lifted up on the mountains, see ye; and when the trumpet is blown, hear ye.", "ylt": "All ye inhabitants of the world, And ye dwellers of earth, At the lifting up of an ensign on hills ye look, And at the blowing of a trumpet ye hear.", "dra": "All ye inhabitants of the world, who dwell on the earth, when the sign shall be lifted up on the mountains, you shall see, and you shall hear the sound of the trumpet.", "bbe": "All you peoples of the world, and you who are living on the earth, when a flag is lifted up on the mountains, give attention; and when the horn is sounded, give ear.", "geneva": "Al ye the inhabitants of ye world and dwellers in the earth, shall see when he setteth vp a signe in the mountaines, and when he bloweth the trumpet, ye shall heare.", "wycliffe": "Alle ye dwelleris of the world, that dwellen in the lond, schulen se whanne a signe schal be reisid in the hillis, and ye schulen here the cry of a trumpe.", "rotherham": "All ye inhabitants of the world And ye, that dwell in the earth,—When there is lifted up an ensign on the mountains, Ye shall look, And when there is blown a horn, Ye shall hearken.", "darby": "All ye inhabitants of the world, and dwellers on the earth, when a banner is lifted up on the mountains, see ye, and when a trumpet is blown, hear ye!", "twenty": "", "jps": "All ye inhabitants of the world, and ye dwellers on the earth, when an ensign is lifted up on the mountains, see ye; and when the horn is blown, hear ye.", "acv": "All ye inhabitants of the world, and ye dwellers on the earth, when an ensign is lifted up on the mountains, see ye, and when the trumpet is blown, hear ye.", "anderson": "", "haweis": "", "noyes": "All ye inhabitants of the world, ye that dwell on the earth, When the standard is lifted up on the mountains, behold! When the trumpet is sounded, hear!", "webster": "All ye inhabitants of the world, and dwellers on the earth, see ye, when he lifteth up an ensign on the mountains; and when he bloweth a trumpet, hear ye.", "vulgate": "omnes habitatores orbis qui moramini in terra cum elevatum fuerit signum in montibus videbitis et clangorem tubae audietis;", "brenton": "Now all the rivers of the land shall be inhabited as an inhabited country; their land shall be as when a signal is raised from a mountain; it shall be audible as the sound of a trumpet."}}, {"v": 4, "ref": "18:4", "o": "כִּי֩ כֹ֨ה אָמַ֤ר יְהוָה֙ אֵלַ֔/י אשקוטה אֶשְׁקֳטָ֖ה וְ/אַבִּ֣יטָה בִ/מְכוֹנִ֑/י כְּ/חֹ֥ם צַח֙ עֲלֵי א֔וֹר כְּ/עָ֥ב טַ֖ל בְּ/חֹ֥ם קָצִֽיר", "en": {"kjv": "For so the Lord said unto me, I will take my rest, and I will consider in my dwelling place like a clear heat upon herbs, and like a cloud of dew in the heat of harvest.", "web": "For Yahweh said to me, “I will be still, and I will see in my dwelling place, like clear heat in sunshine, like a cloud of dew in the heat of harvest.”", "bsb": "For this is what the LORD has told me: “I will quietly look on from My dwelling place, like shimmering heat in the sunshine, like a cloud of dew in the heat of harvest.”", "asv": "For thus hath Jehovah said unto me, I will be still, and I will behold in my dwelling-place, like clear heat in sunshine, like a cloud of dew in the heat of harvest.", "ylt": "For thus said Jehovah unto me, `I rest, and I look on My settled place, As a clear heat on an herb. As a thick cloud of dew in the heat of harvest.", "dra": "For thus saith the Lord to me: I will take my rest, and consider in my place, as the noon light is clear, and as a cloud of dew in the day of harvest.", "bbe": "For this is what the Lord has said to me: I will be quiet, watching from my place; like the clear heat when the sun is shining, like a mist of dew in the heat of summer.", "geneva": "For so the Lord saide vnto me, I will rest and beholde in my tabernacle, as the heate drying vp the rayne, and as a cloude of dewe in the heate of haruest.", "wycliffe": "For whi the Lord seith these thingis to me, Y schal reste, and Y schal biholde in my place, as the myddai liyt is cleer, and as a cloude of dew in the dai of heruest.", "rotherham": "For, thus, said Yahweh unto me,—I must be quiet I must look on in my fixed place of abode,—Like a bright heat on the light, Like a cloud of dew in the heat of harvest.", "darby": "For thus hath Jehovah said unto me: I will take my rest, and I will observe from my dwelling-place like clear heat upon herbs, like a cloud of dew in the heat of harvest.", "twenty": "", "jps": "For thus hath HaShem said unto me: I will hold Me still, and I will look on in My dwelling-place, like clear heat in sunshine, like a cloud of dew in the heat of harvest.", "acv": "For thus Jehovah has said to me, I will be still, and I will behold in my dwelling-place, like clear heat in sunshine, like a cloud of dew in the heat of harvest.", "anderson": "", "haweis": "", "noyes": "For thus hath Jehovah said to me: \"I will sit still, and look on from my dwelling-place, Like a serene heat when the sun shineth, Like a dewy cloud in the heat of harvest.\"", "webster": "For so the LORD said to me, I will take my rest, and I will consider in my dwelling-place like a clear heat upon herbs, [and] like a cloud of dew in the heat of harvest.", "vulgate": "quia haec dicit Dominus ad me quiescam et considerabo in loco meo sicut meridiana lux clara est et sicut nubes roris in die messis;", "brenton": "For thus said the Lord to me, There shall be security in my city, as the light of noonday heat, and it shall be as a cloud of dew in the day of harvest."}}, {"v": 5, "ref": "18:5", "o": "כִּֽי לִ/פְנֵ֤י קָצִיר֙ כְּ/תָם פֶּ֔רַח וּ/בֹ֥סֶר גֹּמֵ֖ל יִֽהְיֶ֣ה נִצָּ֑ה וְ/כָרַ֤ת הַ/זַּלְזַלִּים֙ בַּ/מַּזְמֵר֔וֹת וְ/אֶת הַ/נְּטִישׁ֖וֹת הֵסִ֥יר הֵתַֽז", "en": {"kjv": "For afore the harvest, when the bud is perfect, and the sour grape is ripening in the flower, he shall both cut off the sprigs with pruning hooks, and take away and cut down the branches.", "web": "For before the harvest, when the blossom is over, and the flower becomes a ripening grape, he will cut off the sprigs with pruning hooks, and he will cut down and take away the spreading branches.", "bsb": "For before the harvest, when the blossom is gone and the flower becomes a ripening grape, He will cut off the shoots with a pruning knife and remove and discard the branches.", "asv": "For before the harvest, when the blossom is over, and the flower becometh a ripening grape, he will cut off the sprigs with pruning-hooks, and the spreading branches will he take away and cut down.", "ylt": "For before harvest, when the flower is perfect, And the blossom is producing unripe fruit, Then hath one cut the sprigs with pruning hooks, And the branches he hath turned aside, cut down.", "dra": "For before the harvest it was all flourishing, and it shall bud without perfect ripeness, and the sprigs thereof shall be cut off with pruning hooks: and what is left shall be cut away and shaken out.", "bbe": "For before the time of getting in the grapes, after the opening of the bud, when the flower has become a grape ready for crushing, he will take away the small branches with knives, cutting down and taking away the wide-stretching branches.", "geneva": "For afore the haruest when the floure is finished, and the fruite is riping in the floure, then he shall cut downe the branches with hookes, and shall take away, and cut off the boughes:", "wycliffe": "For whi al flouride out bifore heruest, aud vnripe perfeccioun buriownede; and the litle braunchis therof schulen be kit doun with sithis, and tho that ben left, schulen be kit awei. Thei schulen be schakun out,", "rotherham": "For before harvest, when the bud is perfect, And, the blossom, becometh a ripening grape, Then will one cut down the twigs with pruning-hooks, And the tendrils, will he remove [and] cast down:", "darby": "For before the harvest, when the blossoming is over, and the flower becometh a ripening grape, he shall both cut off the sprigs with pruning-knives, and take away [and] cut down the branches.", "twenty": "", "jps": "For before the harvest, when the blossom is over, and the bud becometh a ripening grape, He will cut off the sprigs with pruning-hooks, and the shoots will He take away and lop off.", "acv": "For before the harvest, when the blossom is over, and the flower becomes a ripening grape, he will cut off the sprigs with pruning-hooks, and he will take away and cut down the spreading branches.", "anderson": "", "haweis": "", "noyes": "But before the vintage, when the bud is gone, And the blossom is ripening into a swelling grape, He shall cut off the shoots with pruning-hooks, And the branches he shall take away and cut down.", "webster": "For before the harvest, when the bud is perfect, and the sour grape is ripening in the flower, he shall both cut off the sprigs with pruning-hooks, and take away [and] cut down the branches.", "vulgate": "ante messem enim totus effloruit et inmatura perfectio germinabit et praecidentur ramusculi eius falcibus et quae derelicta fuerint abscidentur excutientur;", "brenton": "Before the reaping time, when the flower has been completely formed, and the unripe grape has put forth its flower and blossomed, then shall he take away the little clusters with pruning-hooks, and shall take away the small branches, and cut them off;"}}, {"v": 6, "ref": "18:6", "o": "יֵעָזְב֤וּ יַחְדָּו֙ לְ/עֵ֣יט הָרִ֔ים וּֽ/לְ/בֶהֱמַ֖ת הָ/אָ֑רֶץ וְ/קָ֤ץ עָלָי/ו֙ הָ/עַ֔יִט וְ/כָל בֶּהֱמַ֥ת הָ/אָ֖רֶץ עָלָ֥י/ו תֶּחֱרָֽף", "en": {"kjv": "They shall be left together unto the fowls of the mountains, and to the beasts of the earth: and the fowls shall summer upon them, and all the beasts of the earth shall winter upon them.", "web": "They will be left together for the ravenous birds of the mountains, and for the animals of the earth. The ravenous birds will summer on them, and all the animals of the earth will winter on them.", "bsb": "They will all be left to the mountain birds of prey, and to the beasts of the land. The birds will feed on them in summer, and all the wild animals in winter.", "asv": "They shall be left together unto the ravenous birds of the mountains, and to the beasts of the earth; and the ravenous birds shall summer upon them, and all the beasts of the earth shall winter upon them.", "ylt": "They are left together to the ravenous fowl of the mountains, And to the beast of the earth, And summered on them hath the ravenous fowl, And every beast of the earth wintereth on them.", "dra": "And they shall be left together to the birds of the mountains, and the beasts of the earth: and the fowls shall be upon them all the summer, and all the beasts of the earth shall winter upon them.", "bbe": "They will be for the birds of the mountains, and for the beasts of the earth: the birds will come down on them in the summer, and the beasts of the earth in the winter.", "geneva": "They shall be left together vnto the foules of the mountaines, and to the beastes of the earth: for the foule shall sommer vpon it, and euery beast of the earth shall winter vpon it.", "wycliffe": "and schulen be left togidere to the briddis of hillis, and to the beestis of erthe; and briddis schulen be on hym by a somer euerlastinge, and alle the beestis of erthe schulen dwelle bi wyntir on hym.", "rotherham": "They shall be left together. To the ravenous birds, of the mountains, And to the beast of the earth,—Then shall the ravenous bird, summer upon them, And, every beast of the earth, upon them, shall winter.", "darby": "They shall be left together unto the mountain birds of prey, and to the beasts of the earth; and the birds of prey shall summer upon them, and all the beasts of the earth shall winter upon them.", "twenty": "", "jps": "They shall be left together unto the ravenous birds of the mountains, and to the beasts of the earth; and the ravenous birds shall summer upon them, and all the beasts of the earth shall winter upon them.", "acv": "They shall be left together to the ravenous birds of the mountains, and to the beasts of the earth. And the ravenous birds shall summer upon them, and all the beasts of the earth shall winter upon them.", "anderson": "", "haweis": "", "noyes": "They shall be left together to the ravenous birds of the mountains, And to the wild beasts of the earth. The ravenous birds shall summer upon it, And every wild beast of the earth shall winter upon it.", "webster": "They shall be left together to the fowls of the mountains, and to the beasts of the earth: and the fowls shall summer upon them, and all the beasts of the earth shall winter upon them.", "vulgate": "et relinquentur simul avibus montium et bestiis terrae et aestate perpetua erunt super eum volucres et omnes bestiae terrae super illum hiemabunt;", "brenton": "And he shall leave them together to the birds of the sky, and to the wild beasts of the earth: and the fowls of the sky shall be gathered upon them, and all the beasts of the land shall come upon him."}}, {"v": 7, "ref": "18:7", "o": "בָּ/עֵת֩ הַ/הִ֨יא יֽוּבַל שַׁ֜י לַ/יהוָ֣ה צְבָא֗וֹת עַ֚ם מְמֻשָּׁ֣ךְ וּ/מוֹרָ֔ט וּ/מֵ/עַ֥ם נוֹרָ֖א מִן ה֣וּא וָ/הָ֑לְאָה גּ֣וֹי קַו קָ֣ו וּ/מְבוּסָ֗ה אֲשֶׁ֨ר בָּזְא֤וּ נְהָרִים֙ אַרְצ֔/וֹ אֶל מְק֛וֹם שֵׁם יְהוָ֥ה צְבָא֖וֹת הַר צִיּֽוֹן", "en": {"kjv": "In that time shall the present be brought unto the Lord of hosts of a people scattered and peeled, and from a people terrible from their beginning hitherto; a nation meted out and trodden under foot, whose land the rivers have spoiled, to the place of the name of the Lord of hosts, the mount Zion.", "web": "In that time, a present will be brought to Yahweh of Armies from a people tall and smooth, even from a people awesome from their beginning onward, a nation that measures out and treads down, whose land the rivers divide, to the place of the name of Yahweh of Armies, Mount Zion.", "bsb": "At that time gifts will be brought to the LORD of Hosts— from a people tall and smooth-skinned, from a people widely feared, from a powerful nation of strange speech, whose land is divided by rivers— to Mount Zion, the place of the Name of the LORD of Hosts.", "asv": "In that time shall a present be brought unto Jehovah of hosts from a people tall and smooth, even from a people terrible from their beginning onward, a nation that meteth out and treadeth down, whose land the rivers divide, to the place of the name of Jehovah of hosts, the mount Zion.", "ylt": "At that time brought is a present to Jehovah of Hosts, A nation drawn out and peeled. Even of a people fearful from the beginning hitherto, A nation meting out by line, and treading down, Whose land floods have spoiled, Unto the place of the name of Jehovah of Hosts--mount Zion!'", "dra": "At that time shall a present be brought to the Lord of hosts, from a people rent and torn in pieces: from a terrible people, after which there hath been no other: from a nation expecting, expecting and trodden under foot, whose land the rivers have spoiled, to the place of the name of the Lord of hosts, to mount Sion.", "bbe": "In that time an offering will be made to the Lord of armies from a people tall and smooth, causing fear through all their history; a strong nation, crushing down its haters, whose land is cut through by rivers, an offering taken to the place of the name of the Lord of armies, even Mount Zion.", "geneva": "At that time shall a present be brought vnto the Lord of hostes, (a people that is scattered abroade, and spoyled, and of a terrible people from their beginning hitherto, a nation, by litle and litle euen troden vnder foote, whose land the riuers haue spoyled) to the place of the Name of the Lord of hostes, euen the mount Zion.", "wycliffe": "In that tyme a yifte schal be brouyt to the Lord of oostis, of the puple drawun up and to-rent; of the puple ferdful, aftir which was noon other; of the folk abidynge and defoulid, whos lond floodis rauyschiden; the yifte schal be brouyt to the place of the name of the Lord of oostis, to the hil of Sion.", "rotherham": "In that time, shall there be borne along. As a present unto Yahweh of hosts A people drawn out and polished, Even from a people terrible from their beginning and onwards,—nation most mighty and subduing Whose land rivers, have cut through, Unto the place of the Name of Yahweh of hosts. Mount Zion.", "darby": "In that time shall a present be brought unto Jehovah of hosts of a people scattered and ravaged, — and from a people terrible from their existence and thenceforth, a nation of continued waiting and of treading down, whose land the rivers have spoiled, ...to the place of the name of Jehovah of hosts, the mount Zion.", "twenty": "", "jps": "In that time shall a present be brought unto HaShem of hosts of a people tall and of glossy skin, and from a people terrible from their beginning onward; a nation that is sturdy and treadeth down, whose land the rivers divide, to the place of the name of HaShem of hosts, the mount Zion.", "acv": "In that time a present shall be brought to Jehovah of hosts from a people tall and smooth, even from a people fearful from their beginning onward, a nation that metes out and treads down, whose land the rivers divide, to the place of the name of Jehovah of hosts, the mount Zion.", "anderson": "", "haweis": "", "noyes": "At that time shall gifts be brought to Jehovah of hosts From a nation tall and fair, From a people terrible from the first and onward, A mighty, victorious people, Whose land is divided by rivers, To the dwelling-place of Jehovah of hosts, to mount Zion.", "webster": "In that time shall the present be brought to the LORD of hosts of a people scattered and peeled, and from a people terrible from their beginning hitherto; a nation measured by line and trodden under foot, whose land the rivers have spoiled, to the place of the name of the LORD of hosts, the mount Zion.", "vulgate": "in tempore illo deferetur munus Domino exercituum a populo divulso et dilacerato a populo terribili post quem non fuit alius a gente expectante expectante et conculcata cuius diripuerunt flumina terram eius ad locum nominis Domini exercituum montem Sion;", "brenton": "In that time shall presents be brought to the Lord of hosts from a people afflicted and peeled, and from a people great from henceforth and for ever; a nation hoping and yet trodden down, which is in a part of a river of his land, to the place where is the name of the Lord of hosts, the mount Sion."}}]}, {"c": 19, "verses": [{"v": 1, "ref": "19:1", "o": "מַשָּׂ֖א מִצְרָ֑יִם הִנֵּ֨ה יְהוָ֜ה רֹכֵ֨ב עַל עָ֥ב קַל֙ וּ/בָ֣א מִצְרַ֔יִם וְ/נָע֞וּ אֱלִילֵ֤י מִצְרַ֨יִם֙ מִ/פָּנָ֔י/ו וּ/לְבַ֥ב מִצְרַ֖יִם יִמַּ֥ס בְּ/קִרְבּֽ/וֹ", "en": {"kjv": "The burden of Egypt. Behold, the Lord rideth upon a swift cloud, and shall come into Egypt: and the idols of Egypt shall be moved at his presence, and the heart of Egypt shall melt in the midst of it.", "web": "The burden of Egypt: “Behold, Yahweh rides on a swift cloud, and comes to Egypt. The idols of Egypt will tremble at his presence; and the heart of Egypt will melt in its midst.", "bsb": "This is the burden against Egypt: Behold, the LORD rides on a swift cloud; He is coming to Egypt. The idols of Egypt will tremble before Him, and the hearts of the Egyptians will melt within them.", "asv": "The burden of Egypt. Behold, Jehovah rideth upon a swift cloud, and cometh unto Egypt: and the idols of Egypt shall tremble at his presence; and the heart of Egypt shall melt in the midst of it.", "ylt": "The burden of Egypt. Lo, Jehovah is riding on a swift thick cloud, And He hath entered Egypt, And moved have been the idols of Egypt at His presence, And the heart of Egypt melteth in its midst.", "dra": "The burden of Egypt. Behold the Lord will ascend upon a swift cloud, and will enter into Egypt, and the idols of Egypt shall be moved at his presence, and the heart of Egypt shall melt in the midst thereof.", "bbe": "The word about Egypt. See, the Lord is seated on a quick-moving cloud, and is coming to Egypt: and the false gods of Egypt will be troubled at his coming, and the heart of Egypt will be turned to water.", "geneva": "The burden of Egypt. Beholde, the Lord rideth vpon a swift cloude, and shall come into Egypt, and the idoles of Egypt shall be moued at his presence, and the heart of Egypt shall melt in the middes of her.", "wycliffe": "The birthun of Egipt. Lo! the Lord schal stie on a liyt cloude, and he schal entre in to Egipt; and the symilacris of Egipt schulen be mouyd fro his face, and the herte of Egipt schal faile in the myddis therof.", "rotherham": "The oracle on Egypt: Lo! Yahweh, riding upon a swift cloud, and he will enter Egypt, And the idols of Egypt shall shake at his presence, And, the heart of Egypt, shall melt within him;", "darby": "The burden of Egypt. Behold, Jehovah rideth upon a swift cloud, and cometh to Egypt; and the idols of Egypt are moved at his presence, and the heart of Egypt melteth in the midst of it.", "twenty": "", "jps": "The burden of Egypt. Behold, HaShem rideth upon a swift cloud, and cometh unto Egypt; and the idols of Egypt shall be moved at His presence, and the heart of Egypt shall melt within it.", "acv": "The burden of Egypt. Behold, Jehovah rides upon a swift cloud, and comes to Egypt. And the idols of Egypt shall tremble at his presence, and the heart of Egypt shall melt in the midst of it.", "anderson": "", "haweis": "", "noyes": "The prophecy concerning Egypt. Behold, Jehovah rideth upon a swift cloud, And cometh to Egypt; The gods of Egypt tremble at his presence, And the heart of Egypt melteth within her.", "webster": "The burden of Egypt. Behold, the LORD rideth upon a swift cloud, and will come into Egypt: and the idols of Egypt shall be moved at his presence, and the heart of Egypt shall melt in the midst of it.", "vulgate": "onus Aegypti ecce Dominus ascendet super nubem levem et ingredietur Aegyptum et movebuntur simulacra Aegypti a facie eius et cor Aegypti tabescet in medio eius;", "brenton": "THE VISION OF EGYPT. Behold, the Lord sits on a swift cloud, and shall come to Egypt: and the idols of Egypt shall be moved at his presence, and their heart shall faint within them."}}, {"v": 2, "ref": "19:2", "o": "וְ/סִכְסַכְתִּ֤י מִצְרַ֨יִם֙ בְּ/מִצְרַ֔יִם וְ/נִלְחֲמ֥וּ אִישׁ בְּ/אָחִ֖י/ו וְ/אִ֣ישׁ בְּ/רֵעֵ֑/הוּ עִ֣יר בְּ/עִ֔יר מַמְלָכָ֖ה בְּ/מַמְלָכָֽה", "en": {"kjv": "And I will set the Egyptians against the Egyptians: and they shall fight every one against his brother, and every one against his neighbour; city against city, and kingdom against kingdom.", "web": "I will stir up the Egyptians against the Egyptians, and they will fight everyone against his brother, and everyone against his neighbor; city against city, and kingdom against kingdom.", "bsb": "“So I will incite Egyptian against Egyptian; brother will fight against brother, neighbor against neighbor, city against city, and kingdom against kingdom.", "asv": "And I will stir up the Egyptians against the Egyptians: and they shall fight every one against his brother, and every one against his neighbor; city against city, and kingdom against kingdom.", "ylt": "And I armed Egyptians against Egyptians, And they fought, each against his brother, And each against his neighbour, City against city, kingdom against kingdom.", "dra": "And I will set the Egyptians to fight against the Egyptians: and they shall fight brother against brother, and friend against friend, city against city, kingdom against kingdom.", "bbe": "And I will send the Egyptians against the Egyptians: and they will be fighting every one against his brother, and every one against his neighbour; town against town, and kingdom against kingdom.", "geneva": "And I will set the Egyptians against the Egyptians: so euery one shall fight against his brother, and euery one against his neighbour, citie against citie, and kingdome against kingdome.", "wycliffe": "And Y schal make Egipcians to renne togidere ayens Egipcians, and a man schal fiyte ayens his brother, and a man ayens his frend, a citee ayens a citee, and a rewme ayens a rewme.", "rotherham": "And I will stir up Egyptians against Egyptians, And they shall fight—Every one against his brother and Every one against his neighbour,—City against city, and Kingdom against kingdom.", "darby": "And I will incite the Egyptians against the Egyptians; and they shall fight every one against his brother, and every one against his neighbour; city against city, kingdom against kingdom.", "twenty": "", "jps": "And I will spur Egypt against Egypt; and they shall fight every one against his brother, and everyone against his neighbour; city against city, and kingdom against kingdom.", "acv": "And I will stir up the Egyptians against the Egyptians, and they shall fight each one against his brother, and each one against his neighbor, city against city, kingdom against kingdom.", "anderson": "", "haweis": "", "noyes": "\"I will set the Egyptians against the Egyptians; Brother shall fight against brother, And neighbor against neighbor; City against city, And kingdom against kingdom.", "webster": "And I will set the Egyptians against the Egyptians: and they shall fight every one against his brother, and every one against his neighbor; city against city, [and] kingdom against kingdom.", "vulgate": "et concurrere faciam Aegyptios adversum Aegyptios et pugnabit vir contra fratrem suum et vir contra amicum suum civitas adversus civitatem regnum adversus regnum;", "brenton": "And the Egyptians shall be stirred up against the Egyptians: and a man shall fight against his brother, and a man against his neighbor, city against city, and law against law."}}, {"v": 3, "ref": "19:3", "o": "וְ/נָבְקָ֤ה רֽוּחַ מִצְרַ֨יִם֙ בְּ/קִרְבּ֔/וֹ וַ/עֲצָת֖/וֹ אֲבַלֵּ֑עַ וְ/דָרְשׁ֤וּ אֶל הָֽ/אֱלִילִים֙ וְ/אֶל הָ֣/אִטִּ֔ים וְ/אֶל הָ/אֹב֖וֹת וְ/אֶל הַ/יִּדְּעֹנִֽים", "en": {"kjv": "And the spirit of Egypt shall fail in the midst thereof; and I will destroy the counsel thereof: and they shall seek to the idols, and to the charmers, and to them that have familiar spirits, and to the wizards.", "web": "The spirit of Egypt will fail in its midst. I will destroy its counsel. They will seek the idols, the charmers, those who have familiar spirits, and the wizards.", "bsb": "Then the spirit of the Egyptians will be emptied out from among them, and I will frustrate their plans, so that they will resort to idols and spirits of the dead, to mediums and spiritists.", "asv": "And the spirit of Egypt shall fail in the midst of it; and I will destroy the counsel thereof: and they shall seek unto the idols, and to the charmers, and to them that have familiar spirits, and to the wizards.", "ylt": "And emptied out hath been in its midst the spirit of Egypt. And its counsel I swallow up, And they have sought unto the idols, And unto the charmers, And unto those having familiar spirits, And unto the wizards.", "dra": "And the spirit of Egypt shall be broken in the bowels thereof, and I will cast down their counsel: and they shall consult their idols, and their diviners, and their wizards, and soothsayers.", "bbe": "And the spirit of Egypt will be troubled in her, and I will make her decisions without effect: and they will be turning to the false gods, and to those who make hollow sounds, and to those who have control of spirits, and to those who are wise in secret arts.", "geneva": "And the spirite of Egypt shall faile in the middes of her, and I will destroy their counsell, and they shall seeke at the idoles, and at the sorcerers, and at them that haue spirits of diuination, and at the southsayers.", "wycliffe": "And the spirit of Egipt schal be brokun in the entrailis therof, and Y schal caste doun the councel therof; and thei schulen axe her symylacris, and her false diuinouris, and her men that han vncleene spiritis spekinge in the wombe, and her dyuynouris bi sacrifices maad on auteris to feendis.", "rotherham": "And the spirit of Egypt, shall vanish, within them, Yea the sagacity thereof, will I swallow up,—And they will seek Unto the idols and Unto them that mutter, and Unto them that have familiar spirits, and Unto the wizards;", "darby": "And the spirit of Egypt shall fail in the midst of it, and I will destroy the counsel thereof; and they shall seek unto the idols and unto the conjurers, and unto the necromancers, and unto the soothsayers.", "twenty": "", "jps": "And the spirit of Egypt shall be made empty within it; and I will make void the counsel thereof; and they shall seek unto the idols, and to the whisperers, and to the ghosts, and to the familiar spirits.", "acv": "And the spirit of Egypt shall fail in the midst of it, and I will destroy the counsel of it. And they shall seek for the idols, and for the charmers, and for those who have familiar spirits, and for the wizards.", "anderson": "", "haweis": "", "noyes": "The spirit of Egypt shall fail within her, And her devices I will bring to naught. Then shall they consult the idols, and the sorcerers, And the necromancers, and the wizards.", "webster": "And the spirit of Egypt shall fail in the midst of her, and I will destroy her counsel: and they shall seek to the idols, and to the charmers, and to them that have familiar spirits, and to the wizards.", "vulgate": "et disrumpetur spiritus Aegypti in visceribus eius et consilium eius praecipitabo et interrogabunt simulacra sua et divinos suos et pythones et ariolos;", "brenton": "And the spirit of the Egyptians shall be troubled within them; and I will frustrate their counsel: and they shall enquire of their gods and their images, and them that speak out of the earth, and them that have in them a divining spirit."}}, {"v": 4, "ref": "19:4", "o": "וְ/סִכַּרְתִּי֙ אֶת מִצְרַ֔יִם בְּ/יַ֖ד אֲדֹנִ֣ים קָשֶׁ֑ה וּ/מֶ֤לֶךְ עַז֙ יִמְשָׁל בָּ֔/ם נְאֻ֥ם הָ/אָד֖וֹן יְהוָ֥ה צְבָאֽוֹת", "en": {"kjv": "And the Egyptians will I give over into the hand of a cruel lord; and a fierce king shall rule over them, saith the Lord, the Lord of hosts.", "web": "I will give over the Egyptians into the hand of a cruel lord. A fierce king will rule over them,” says the Lord, Yahweh of Armies.", "bsb": "I will deliver the Egyptians into the hands of harsh masters, and a fierce king will rule over them,” declares the Lord GOD of Hosts.", "asv": "And I will give over the Egyptians into the hand of a cruel lord; and a fierce king shall rule over them, saith the Lord, Jehovah of hosts.", "ylt": "And I have delivered the Egyptians Into the hand of a hard lord, And a strong king doth rule over them, An affirmation of the Lord, Jehovah of Hosts.", "dra": "And I will deliver Egypt into the hand of cruel masters, and a strong king shall rule over them, saith the Lord the God of hosts.", "bbe": "And I will give the Egyptians into the hand of a cruel lord; and a hard king will be their ruler, says the Lord, the Lord of armies.", "geneva": "And I will deliuer the Egyptians into the hand of the cruell Lordes, and a mightie King shall rule ouer them, sayth the Lord God of hostes.", "wycliffe": "And Y schal bitake Egipt in to the hond of cruel lordis, and a strong kyng schal be lord of hem, seith the Lord God of oostis.", "rotherham": "And I will deliver the Egyptians into the hand of a cruel lord,—And a fierce king shall rule over them, Declareth the Lord, Yahweh of hosts.", "darby": "And the Egyptians will I give over into the hand of a cruel lord, and a fierce king shall rule over them, saith the Lord, Jehovah of hosts.", "twenty": "", "jps": "And I will give over the Egyptians into the hand of a cruel lord; and a fierce king shall rule over them, saith the L-rd, HaShem of hosts.", "acv": "And I will give over the Egyptians into the hand of a cruel lord. And a fierce king shall rule over them, says the Lord, Jehovah of hosts.", "anderson": "", "haweis": "", "noyes": "But I will give up the Egyptians to the hands of a cruel lord, And a fierce king shall rule over them,\" Saith the Lord, Jehovah of hosts.", "webster": "And the Egyptians will I give over into the hand of a cruel lord; and a fierce king shall rule over them, saith the Lord, the LORD of hosts.", "vulgate": "et tradam Aegyptum in manu dominorum crudelium et rex fortis dominabitur eorum ait Dominus Deus exercituum;", "brenton": "And I will deliver Egypt into the hands of men, of cruel lords; and cruel kings shall rule over them: thus saith the Lord of hosts."}}, {"v": 5, "ref": "19:5", "o": "וְ/נִשְּׁתוּ מַ֖יִם מֵֽ/הַ/יָּ֑ם וְ/נָהָ֖ר יֶחֱרַ֥ב וְ/יָבֵֽשׁ", "en": {"kjv": "And the waters shall fail from the sea, and the river shall be wasted and dried up.", "web": "The waters will fail from the sea, and the river will be wasted and become dry.", "bsb": "The waters of the Nile will dry up, and the riverbed will be parched and empty.", "asv": "And the waters shall fail from the sea, and the river shall be wasted and become dry.", "ylt": "And failed have waters from the sea, And a river is wasted and dried up.", "dra": "And the water of the sea shall be dried up, and the river shall be wasted and dry.", "bbe": "And the waters of the sea will be cut off, and the river will become dry and waste:", "geneva": "Then the waters of the sea shall faile, and the riuers shall be dryed vp, and wasted.", "wycliffe": "And watir of the see schal wexe drie, and the flood schal be desolat, and schal be dried.", "rotherham": "And the waters shall be dried up from the great stream,—And the River, shall waste and be dry;", "darby": "And the waters shall fail from the sea, and the river shall be wasted and dried up;", "twenty": "", "jps": "And the waters shall fail from the sea, and the river shall be drained dry,", "acv": "And the waters shall fail from the sea, and the river shall be wasted and become dry.", "anderson": "", "haweis": "", "noyes": "Then shall the waters fail from the river, Yea, the river shall be wasted and dried up.", "webster": "And the waters shall fail from the sea, and the rivers shall be wasted and dried up.", "vulgate": "et arescet aqua de mari et fluvius desolabitur atque siccabitur;", "brenton": "And the Egyptians shall drink the water that is by the sea, but the river shall fail, and be dried up."}}, {"v": 6, "ref": "19:6", "o": "וְ/הֶאֶזְנִ֣יחוּ נְהָר֔וֹת דָּלֲל֥וּ וְ/חָרְב֖וּ יְאֹרֵ֣י מָצ֑וֹר קָנֶ֥ה וָ/ס֖וּף קָמֵֽלוּ", "en": {"kjv": "And they shall turn the rivers far away; and the brooks of defence shall be emptied and dried up: the reeds and flags shall wither.", "web": "The rivers will become foul. The streams of Egypt will be diminished and dried up. The reeds and flags will wither away.", "bsb": "The canals will stink; the streams of Egypt will trickle and dry up; the reeds and rushes will wither.", "asv": "And the rivers shall become foul; the streams of Egypt shall be diminished and dried up; the reeds and flags shall wither away.", "ylt": "And they have turned away the flowings, Weak and dried up have been brooks of the bulwark, Reed and flag have withered.", "dra": "And the rivers shall fail: the streams of the banks shall be diminished, and be dried up. The reed and the bulrush shall wither away.", "bbe": "And the rivers will have an evil smell; the stream of Egypt will become small and dry: all the water-plants will come to nothing.", "geneva": "And the riuers shall goe farre away: the riuers of defence shalbe emptied and dryed vp: the reedes and flagges shall be cut downe.", "wycliffe": "And the floodis schulen faile, and the strondis of the feeldis schulen be maad thynne, and schulen be dried; a rehed and spier schal fade.", "rotherham": "And rivers, shall stink, The canals of Egypt be shallow and waste, Reed and rush, be withered;", "darby": "and the rivers shall stink, and the streams of Egypt shall be diminished and drain away: the reeds and sedges shall wither.", "twenty": "", "jps": "And the rivers shall become foul; the streams of Egypt shall be minished and dried up; the reeds and flags shall wither.", "acv": "And the rivers shall become foul. The streams of Egypt shall be diminished and dried up. The reeds and flags shall wither away.", "anderson": "", "haweis": "", "noyes": "The streams shall become putrid; The canals of Egypt shall be emptied and dried up; The reed and the rush shall wither.", "webster": "And they shall turn the rivers far away; [and] the brooks of defense shall be emptied and dried up: the reeds and flags shall wither.", "vulgate": "et deficient flumina adtenuabuntur et siccabuntur rivi aggerum calamus et iuncus marcescet;", "brenton": "And the streams shall fail, and the canals of the river; and every reservoir of water shall be dried up, in every marsh also of reed and papyrus."}}, {"v": 7, "ref": "19:7", "o": "עָר֥וֹת עַל יְא֖וֹר עַל פִּ֣י יְא֑וֹר וְ/כֹל֙ מִזְרַ֣ע יְא֔וֹר יִיבַ֥שׁ נִדַּ֖ף וְ/אֵינֶֽ/נּוּ", "en": {"kjv": "The paper reeds by the brooks, by the mouth of the brooks, and every thing sown by the brooks, shall wither, be driven away, and be no more.", "web": "The meadows by the Nile, by the brink of the Nile, and all the sown fields of the Nile, will become dry, be driven away, and be no more.", "bsb": "The bulrushes by the Nile, by the mouth of the river, and all the fields sown along the Nile, will wither, blow away, and be no more.", "asv": "The meadows by the Nile, by the brink of the Nile, and all the sown fields of the Nile, shall become dry, be driven away, and be no more.", "ylt": "Exposed things by the brook, by the edge of the brook, And every sown thing of the brook, hath withered, It hath been driven away, and is not.", "dra": "The channel of the river shall be laid bare from its fountain, and every thing sown by the water shall be dried up, it shall wither away, and shall be no more.", "bbe": "The grass-lands by the Nile, and everything planted by the Nile, will become dry, or taken away by the wind, and will come to an end.", "geneva": "The grasse in the riuer, and at the head of the riuers, and all that groweth by the riuer, shall wither, and be driuen away, and be no more.", "wycliffe": "The botme of watir schal be maad nakid, and stremys fro her welle; and the moiste place of al seed schal be dried, schal waxe drie, and schal not be.", "rotherham": "The meadows by the Nile, by the mouth of the Nile. And all that is sown in the Nile, Shall be dry, driven away, and not be!", "darby": "The meadows by the Nile, on the banks of the Nile, and everything sown by the Nile, shall be dried up, be driven away, and be no [more].", "twenty": "", "jps": "The mosses by the Nile, by the brink of the Nile, and all that is sown by the Nile, shall become dry, be driven away, and be no more.", "acv": "The meadows by the Nile, by the brink of the Nile, and all the sown fields of the Nile, shall become dry, be driven away, and be no more.", "anderson": "", "haweis": "", "noyes": "The meadows by the river, by the borders of the river, And all that groweth by the river, Shall wither, be blasted, and be no more.", "webster": "The paper-reeds by the brooks, by the mouth of the brooks, and every thing sown by the brooks, shall wither, be driven away, and be no [more].", "vulgate": "nudabitur alveus rivi a fonte suo et omnis sementis inrigua siccabitur arescet et non erit;", "brenton": "And all the green herbage round about the river, and everything sown by the side of the river, shall be blasted with the wind and dried up."}}, {"v": 8, "ref": "19:8", "o": "וְ/אָנוּ֙ הַ/דַּיָּגִ֔ים וְ/אָ֣בְל֔וּ כָּל מַשְׁלִיכֵ֥י בַ/יְא֖וֹר חַכָּ֑ה וּ/פֹרְשֵׂ֥י מִכְמֹ֛רֶת עַל פְּנֵי מַ֖יִם אֻמְלָֽלוּ", "en": {"kjv": "The fishers also shall mourn, and all they that cast angle into the brooks shall lament, and they that spread nets upon the waters shall languish.", "web": "The fishermen will lament, and all those who fish in the Nile will mourn, and those who spread nets on the waters will languish.", "bsb": "Then the fishermen will mourn, all who cast a hook into the Nile will lament, and those who spread nets on the waters will pine away.", "asv": "And the fishers shall lament, and all they that cast angle into the Nile shall mourn, and they that spread nets upon the waters shall languish.", "ylt": "And lamented have the fishers, And mourned have all casting angle into a brook, And those spreading nets on the face of the waters have languished.", "dra": "The fishers also shall mourn, and all that cast a hook into the river shall lament, and they that spread nets upon the waters shall languish away.", "bbe": "The fishermen will be sad, and all those who put fishing-lines into the Nile will be full of grief, and those whose nets are stretched out on the waters will have sorrow in their hearts.", "geneva": "The fishers also shall mourne, and all they that cast angle into the riuer, shall lament, and they that spread their nette vpon the waters, shall be weakened.", "wycliffe": "And fischeris schulen morne, and alle that casten hook in to the flood, schulen weile; and thei that spreden abrood a net on the face of watris, schulen fade.", "rotherham": "Then shall the fishers, lament, And all shall mourn who cast in the Nile a hook,—And they who spread nets on the face of the waters shall languish;", "darby": "And the fishers shall mourn, and all they that cast fish-hook into the Nile shall lament, and they that spread net upon the waters shall languish.", "twenty": "", "jps": "The fishers also shall lament, and all they that cast angle into the Nile shall mourn, and they that spread nets upon the waters shall languish.", "acv": "And the fishermen shall lament, and all those who cast a hook into the Nile shall mourn, and those who spread nets upon the waters shall languish.", "anderson": "", "haweis": "", "noyes": "Then shall the fishermen mourn; All they that cast the hook into the river shall lament, And they that spread nets upon the face of the waters shall languish.", "webster": "The fishers also shall mourn, and all they that cast angle into the brooks shall lament, and they that spread nets upon the waters shall languish.", "vulgate": "et maerebunt piscatores et lugebunt omnes mittentes in flumen hamum et expandentes rete super faciem aquae marcescent;", "brenton": "And the fishermen shall groan, and all that cast a hook into the river shall groan; they also that cast nets, and the anglers shall mourn."}}, {"v": 9, "ref": "19:9", "o": "וּ/בֹ֛שׁוּ עֹבְדֵ֥י פִשְׁתִּ֖ים שְׂרִיק֑וֹת וְ/אֹרְגִ֖ים חוֹרָֽי", "en": {"kjv": "Moreover they that work in fine flax, and they that weave networks, shall be confounded.", "web": "Moreover those who work in combed flax, and those who weave white cloth, will be confounded.", "bsb": "The workers in flax will be dismayed, and the weavers of fine linen will turn pale.", "asv": "Moreover they that work in combed flax, and they that weave white cloth, shall be confounded.", "ylt": "And ashamed have been makers of fine flax, And weavers of net-works.", "dra": "They shall be confounded that wrought in flax, combing and weaving fine linen.", "bbe": "And all the workers in linen thread, and those who make cotton cloth, will be put to shame.", "geneva": "Moreouer, they that worke in flaxe of diuers sortes, shall be confounded, and they that weaue nettes.", "wycliffe": "Thei schulen be schent, that wrouyten flex, foldynge and ordeynynge sutil thingis.", "rotherham": "Then shall turn pale The workers in combed flax,—and The weavers of white linen;", "darby": "And they that work in fine flax, and they that weave white stuffs shall be ashamed.", "twenty": "", "jps": "Moreover they that work in combed flax, and they that weave cotton, shall be ashamed.", "acv": "Moreover those who work in combed flax, and those who weave white cloth, shall be confounded.", "anderson": "", "haweis": "", "noyes": "They, also, that work in flax, And they that weave white linen, shall be confounded.", "webster": "Moreover they that work in fine flax, and they that weave net-works shall be confounded.", "vulgate": "confundentur qui operabantur linum pectentes et texentes subtilia;", "brenton": "And shame shall come upon them that work fine flax, and them that make fine linen."}}, {"v": 10, "ref": "19:10", "o": "וְ/הָי֥וּ שָׁתֹתֶ֖י/הָ מְדֻכָּאִ֑ים כָּל עֹ֥שֵׂי שֶׂ֖כֶר אַגְמֵי נָֽפֶשׁ", "en": {"kjv": "And they shall be broken in the purposes thereof, all that make sluices and ponds for fish.", "web": "The pillars will be broken in pieces. All those who work for hire will be grieved in soul.", "bsb": "The workers in cloth will be dejected, and all the hired workers will be sick at heart.", "asv": "And the pillars of Egypt shall be broken in pieces; all they that work for hire shall be grieved in soul.", "ylt": "And its foundations have been smitten, All making wages are afflicted in soul.", "dra": "And its watery places shall be dry, all they shall mourn that made pools to take fishes.", "bbe": "And the makers of twisted thread will be crushed, and those who ... will be sad in heart.", "geneva": "For their nettes shalbe broken, and all they, that make pondes, shalbe heauie in heart.", "wycliffe": "And the watir places therof schulen be drye; alle that maden poondis to take fischis, schulen be schent.", "rotherham": "Then shall her pillars be crushed,—All who make wages, be bowed down in soul.", "darby": "And her pillars shall be broken in pieces, and all workers for hire shall be sad of soul.", "twenty": "", "jps": "And her foundations shall be crushed, all they that make dams shall be grieved in soul.", "acv": "And the pillars of Egypt shall be broken in pieces. All those who work for hire shall be grieved in soul.", "anderson": "", "haweis": "", "noyes": "Her pillars are broken down, And all who labor for hire are grieved in heart.", "webster": "And they shall be broken in the purposes thereof, all that make sluices [and] ponds for fish.", "vulgate": "et erunt inrigua eius flaccentia omnes qui faciebant lacunas ad capiendos pisces;", "brenton": "And they that work at them shall be in pain, and all that make beer shall be grieved, and be pained in their souls."}}, {"v": 11, "ref": "19:11", "o": "אַךְ אֱוִלִים֙ שָׂ֣רֵי צֹ֔עַן חַכְמֵי֙ יֹעֲצֵ֣י פַרְעֹ֔ה עֵצָ֖ה נִבְעָרָ֑ה אֵ֚יךְ תֹּאמְר֣וּ אֶל פַּרְעֹ֔ה בֶּן חֲכָמִ֥ים אֲנִ֖י בֶּן מַלְכֵי קֶֽדֶם", "en": {"kjv": "Surely the princes of Zoan are fools, the counsel of the wise counsellors of Pharaoh is become brutish: how say ye unto Pharaoh, I am the son of the wise, the son of ancient kings?", "web": "The princes of Zoan are utterly foolish. The counsel of the wisest counselors of Pharaoh has become stupid. How do you say to Pharaoh, “I am the son of the wise, the son of ancient kings?”", "bsb": "The princes of Zoan are mere fools; Pharaoh’s wise counselors give senseless advice. How can you say to Pharaoh, “I am one of the wise, a son of eastern kings”?", "asv": "The princes of Zoan are utterly foolish; the counsel of the wisest counsellors of Pharaoh is become brutish: how say ye unto Pharaoh, I am the son of the wise, the son of ancient kings?", "ylt": "Only, fools are the princes of Zoan, The counsel of the wise ones of the counsellors of Pharaoh hath become brutish. How say ye unto Pharaoh, `A son of the wise am I, a son of kings of antiquity?'", "dra": "The princes of Tanis are become fools, the wise counsellors of Pharao have given foolish counsel: how will you say to Pharao: I am the son of the wise, the son of ancient kings?", "bbe": "The chiefs of Zoan are completely foolish; the wisest guides of Pharaoh have become like beasts: how do you say to Pharaoh, I am the son of the wise, the offspring of early kings?", "geneva": "Surely the princes of Zoan are fooles: the counsell of the wise counselers of Pharaoh is become foolish: how say ye vnto Pharaoh, I am the sonne of the wise? I am the sonne of the ancient Kings?", "wycliffe": "The fonned princes of Tafnys, the wise counselouris of Farao, yauen vnwise counsel; hou schulen ye seie to Farao, Y am the sone of wise men, the sone of elde kyngis?", "rotherham": "Surely, foolish, are the princes of Zoan, the wisest counsellors of Pharaoh, in counsel are brutish,—How can ye say unto Pharaoh, Son of the wise, am I Son of the kings of olden time?", "darby": "They are but fools, the princes of Zoan, the wise counsellors of Pharaoh: [their] counsel is become senseless. How say ye unto Pharaoh, I am the son of the wise, the son of ancient kings?", "twenty": "", "jps": "The princes of Zoan are utter fools; the wisest counsellors of Pharaoh are a senseless counsel; how can ye say unto Pharaoh: 'I am the son of the wise, the son of ancient kings'?", "acv": "The rulers of Zoan are utterly foolish. The counsel of the wisest counselors of Pharaoh has become brutish. How will ye say to Pharaoh, I am the son of wise men, the son of ancient kings?", "anderson": "", "haweis": "", "noyes": "Surely the princes of Zoan are fools; The wise counsellors of Pharaoh have been stupid in their counsels. How, then, can ye say to Pharaoh, \"I am the son of the wise, The son of ancient kings\"?", "webster": "Surely the princes of Zoan [are] fools, the counsel of the wise counselors of Pharaoh is become brutish: how say ye to Pharaoh, I [am] the son of the wise, the son of ancient kings?", "vulgate": "stulti principes Taneos sapientes consiliarii Pharao dederunt consilium insipiens quomodo dicetis Pharaoni filius sapientium ego filius regum antiquorum;", "brenton": "And the princes of Tanis shall be fools: as for the king's wise counsellors, their counsel shall be turned into folly: how will ye say to the king, we are sons of wise men, sons of ancient kings?"}}, {"v": 12, "ref": "19:12", "o": "אַיָּ/ם֙ אֵפ֣וֹא חֲכָמֶ֔י/ךָ וְ/יַגִּ֥ידוּ נָ֖א לָ֑/ךְ וְ/יֵ֣דְע֔וּ מַה יָּעַ֛ץ יְהוָ֥ה צְבָא֖וֹת עַל מִצְרָֽיִם", "en": {"kjv": "Where are they? where are thy wise men? and let them tell thee now, and let them know what the Lord of hosts hath purposed upon Egypt.", "web": "Where then are your wise men? Let them tell you now; and let them know what Yahweh of Armies has purposed concerning Egypt.", "bsb": "Where are your wise men now? Let them tell you and reveal what the LORD of Hosts has planned against Egypt.", "asv": "Where then are thy wise men? and let them tell thee now; and let them know what Jehovah of hosts hath purposed concerning Egypt.", "ylt": "Where are they now, thy wise ones? Yea, let them tell to thee, I pray thee, And they know what Jehovah of Hosts hath counselled against Egypt!", "dra": "Where are now thy wise men? let them tell thee, and shew what the Lord of hosts hath purposed upon Egypt.", "bbe": "Where, then, are your wise men? let them make clear to you, let them give you knowledge of the purpose of the Lord of armies for Egypt.", "geneva": "Where are nowe thy wise men, that they may tell thee, or may knowe what the Lord of hostes hath determined against Egypt?", "wycliffe": "Where ben now thi wise men? Telle thei to thee, and schewe thei, what the Lord of oostis thouyte on Egipt.", "rotherham": "Where then are thy wise men? Pray let them tell thee! And let them know what Yahweh of hosts hath purposed on Egypt!", "darby": "Where are they then, thy wise [men]? Let them now tell thee, and let them make known what Jehovah of hosts hath purposed upon Egypt.", "twenty": "", "jps": "Where are they, then, thy wise men? And let them tell thee now; and let them know what HaShem of hosts hath purposed concerning Egypt.", "acv": "Where then are thy wise men? And let them tell thee now, and let them know what Jehovah of hosts has purposed concerning Egypt.", "anderson": "", "haweis": "", "noyes": "Where are they now, thy wise men? Let them tell thee now, so that men may know it, What Jehovah of hosts hath determined concerning Egypt!", "webster": "Where [are] they? where [are] thy wise [men]? and let them tell thee now, and let them know what the LORD of hosts hath purposed upon Egypt.", "vulgate": "ubi sunt nunc sapientes tui adnuntient tibi et indicent quid cogitaverit Dominus exercituum super Aegyptum;", "brenton": "Where are now thy wise men? and let them declare to thee, and say, What has the Lord of hosts purposed upon Egypt?"}}, {"v": 13, "ref": "19:13", "o": "נֽוֹאֲלוּ֙ שָׂ֣רֵי צֹ֔עַן נִשְּׁא֖וּ שָׂ֣רֵי נֹ֑ף הִתְע֥וּ אֶת מִצְרַ֖יִם פִּנַּ֥ת שְׁבָטֶֽי/הָ", "en": {"kjv": "The princes of Zoan are become fools, the princes of Noph are deceived; they have also seduced Egypt, even they that are the stay of the tribes thereof.", "web": "The princes of Zoan have become fools. The princes of Memphis are deceived. They have caused Egypt to go astray, who are the cornerstone of her tribes.", "bsb": "The princes of Zoan have become fools; the princes of Memphis are deceived. The cornerstones of her tribes have led Egypt astray.", "asv": "The princes of Zoan are become fools, the princes of Memphis are deceived; they have caused Egypt to go astray, that are the corner-stone of her tribes.", "ylt": "Foolish have been princes of Zoan, Lifted up have been princes of Noph, And they have caused Egypt to err, The chief of her tribes.", "dra": "The princes of Tanis are become fools, the princes of Memphis are gone astray, they have deceived Egypt, the stay of the people thereof.", "bbe": "The chiefs of Zoan have become foolish, the chiefs of Noph are tricked, the heads of her tribes are the cause of Egypt's wandering out of the way.", "geneva": "The princes of Zoan are become fooles: the princes of Noph are deceiued, they haue deceiued Egypt, euen the corners of the tribes thereof.", "wycliffe": "The princes of Tafnys ben maad foolis; the princes of Memphis fadiden; thei disseyueden Egipt, a corner of the puplis therof.", "rotherham": "Doting are the princes of Zoan, Deceived are the princes of Noph: They who are the corner-stone of her tribes, have led Egypt astray.", "darby": "The princes of Zoan are become foolish, the princes of Noph are deceived; and the corner-stones of its tribes have caused Egypt to err.", "twenty": "", "jps": "The princes of Zoan are become fools, the princes of Noph are deceived; they have caused Egypt to go astray, that are the corner-stone of her tribes.", "acv": "The rulers of Zoan have become fools. The rulers of Memphis are deceived. They have caused Egypt to go astray, the chief of her tribes.", "anderson": "", "haweis": "", "noyes": "The princes of Zoan are become fools; The princes of Noph are deceived, Even the chiefs of her tribes have caused Egypt to err.", "webster": "The princes of Zoan are become fools, the princes of Noph are deceived; they have also seduced Egypt, [even they that are] the support of its tribes.", "vulgate": "stulti facti sunt principes Taneos emarcuerunt principes Mempheos deceperunt Aegyptum angulum populorum eius;", "brenton": "The princes of Tanis have failed, and the princes of Memphis are lifted up with pride, and they shall cause Egypt to wander by tribes."}}, {"v": 14, "ref": "19:14", "o": "יְהוָ֛ה מָסַ֥ךְ בְּ/קִרְבָּ֖/הּ ר֣וּחַ עִוְעִ֑ים וְ/הִתְע֤וּ אֶת מִצְרַ֨יִם֙ בְּ/כָֽל מַעֲשֵׂ֔/הוּ כְּ/הִתָּע֥וֹת שִׁכּ֖וֹר בְּ/קִיאֽ/וֹ", "en": {"kjv": "The Lord hath mingled a perverse spirit in the midst thereof: and they have caused Egypt to err in every work thereof, as a drunken man staggereth in his vomit.", "web": "Yahweh has mixed a spirit of perverseness in the midst of her; and they have caused Egypt to go astray in all of its works, like a drunken man staggers in his vomit.", "bsb": "The LORD has poured into her a spirit of confusion. Egypt has been led astray in all she does, as a drunkard staggers through his own vomit.", "asv": "Jehovah hath mingled a spirit of perverseness in the midst of her; and they have caused Egypt to go astray in every work thereof, as a drunken man staggereth in his vomit.", "ylt": "Jehovah hath mingled in her midst A spirit of perverseness, And they have caused Egypt to err in all its work, As a drunkard erreth in his vomit.", "dra": "The Lord hath mingled in the midst thereof the spirit of giddiness: and they have caused Egypt to err in all its works, as a drunken man staggereth and vomiteth.", "bbe": "The Lord has sent among them a spirit of error: and by them Egypt is turned out of the right way in all her doings, as a man overcome by wine is uncertain in his steps.", "geneva": "The Lord hath mingled among them the spirite of errours: and they haue caused Egypt to erre in euery worke thereof, as a drunken man erreth in his vomite.", "wycliffe": "The Lord meddlid a spirit of errour in the myddis therof; and thei maden Egipt for to erre in al his werk, as a drunkun man and spuynge errith.", "rotherham": "Yahweh, hath infused in her midst, a spirit of perverseness,—And they have led Egypt astray into all his own doings, As a drunken man staggereth into his own vomit;", "darby": "Jehovah hath mingled a spirit of perverseness in the midst thereof; and they have caused Egypt to err in every work thereof, as a drunkard staggereth in his vomit.", "twenty": "", "jps": "HaShem hath mingled within her a spirit of dizziness; and they have caused Egypt to stagger in every work thereof, as a drunken man staggereth in his vomit.", "acv": "Jehovah has mingled a spirit of perverseness in the midst of her, and they have caused Egypt to go astray in every work of it, as a drunken man staggers in his vomit.", "anderson": "", "haweis": "", "noyes": "Jehovah hath mingled within her a spirit of perverseness, And they have caused Egypt to err in all her works, As a drunkard staggereth in his vomit.", "webster": "The LORD hath mingled a perverse spirit in the midst of it: and they have caused Egypt to err in every work of it, as a drunken [man] staggereth in his vomit.", "vulgate": "Dominus miscuit in medio eius spiritum vertiginis et errare fecerunt Aegyptum in omni opere suo sicut errat ebrius et vomens;", "brenton": "For the Lord has prepared for them a spirit of error, and they have caused Egypt to err in all their works, as one staggers who is drunken and vomits also."}}, {"v": 15, "ref": "19:15", "o": "וְ/לֹֽא יִהְיֶ֥ה לְ/מִצְרַ֖יִם מַֽעֲשֶׂ֑ה אֲשֶׁ֧ר יַעֲשֶׂ֛ה רֹ֥אשׁ וְ/זָנָ֖ב כִּפָּ֥ה וְ/אַגְמֽוֹן", "en": {"kjv": "Neither shall there be any work for Egypt, which the head or tail, branch or rush, may do.", "web": "Neither shall there be any work for Egypt, which head or tail, palm branch or rush, may do.", "bsb": "There is nothing Egypt can do— head or tail, palm or reed.", "asv": "Neither shall there be for Egypt any work, which head or tail, palm-branch or rush, may do.", "ylt": "And there is no work to Egypt, That head or tail, branch or reed, may do.", "dra": "And there shall be no work for Egypt, to make head or tail, him that bendeth down, or that holdeth back.", "bbe": "And in Egypt there will be no work for any man, head or tail, high or low, to do.", "geneva": "Neither shall there be any worke in Egypt, which the head may doe, nor the tayle, ye branch nor the rush.", "wycliffe": "And werk schal not be to Egipt, that it make an heed and tail bowynge and refreynynge.", "rotherham": "And Egypt shall have nothing which can be done, Which head or tail, palm-top or rush, can do!", "darby": "Neither shall there be any work for Egypt, which the head or tail, palm-branch or rush, may do.", "twenty": "", "jps": "Neither shall there be for Egypt any work, which head or tail, palm-branch or rush, may do.", "acv": "Neither shall there be for Egypt any work, which head or tail, palm-branch or rush, may do.", "anderson": "", "haweis": "", "noyes": "There shall be nothing which can be done by Egypt, By the head, or the tail, the palm-branch, or the rush.", "webster": "Neither shall there be [any] work for Egypt, which the head or tail, branch or rush, may perform.", "vulgate": "et non erit Aegypto opus quod faciat caput et caudam incurvantem et refrenantem;", "brenton": "And there shall be no work to the Egyptians, which shall make head or tail, or beginning or end."}}, {"v": 16, "ref": "19:16", "o": "בַּ/יּ֣וֹם הַ/ה֔וּא יִֽהְיֶ֥ה מִצְרַ֖יִם כַּ/נָּשִׁ֑ים וְ/חָרַ֣ד וּ/פָחַ֗ד מִ/פְּנֵי֙ תְּנוּפַת֙ יַד יְהוָ֣ה צְבָא֔וֹת אֲשֶׁר ה֖וּא מֵנִ֥יף עָלָֽי/ו", "en": {"kjv": "In that day shall Egypt be like unto women: and it shall be afraid and fear because of the shaking of the hand of the Lord of hosts, which he shaketh over it.", "web": "In that day the Egyptians will be like women. They will tremble and fear because of the shaking of the hand of Yahweh of Armies, which he shakes over them.", "bsb": "In that day the Egyptians will be like women. They will tremble with fear beneath the uplifted hand of the LORD of Hosts, when He brandishes it against them.", "asv": "In that day shall the Egyptians be like unto women; and they shall tremble and fear because of the shaking of the hand of Jehovah of hosts, which he shaketh over them.", "ylt": "In that day is Egypt like women, And it hath mourned, and been afraid, Because of the waving of the hand of Jehovah of Hosts, That He is waving over it.", "dra": "In that day Egypt shall be like unto women, and they shall be amazed, and afraid, because of the moving of the hand of the Lord of hosts, which he shall move over it.", "bbe": "In that day the Egyptians will be like women: and the land will be shaking with fear because of the waving of the Lord's hand stretched out over it.", "geneva": "In that day shall Egypt be like vnto women: for it shall be afraide and feare because of the moouing of the hand of the Lord of hostes, which he shaketh ouer it.", "wycliffe": "In that dai Egipt schal be as wymmen, and thei schulen be astonyed, and schulen drede of the face of the mouynge of the hoond of the Lord of oostis, which he mouede on it.", "rotherham": "In that day, shall Egypt be like unto women,—And shall start and tremble because of the brandishing of the hand of Yahweh of hosts, which he is about to brandish over it.", "darby": "In that day shall Egypt be like unto women; and it shall tremble and fear because of the shaking of the hand of Jehovah of hosts, which he shaketh over it.", "twenty": "", "jps": "In that day shall Egypt be like unto women; and it shall tremble and fear because of the shaking of the hand of HaShem of hosts, which He shaketh over it.", "acv": "In that day the Egyptians shall be like women, and they shall tremble and fear because of the shaking of the hand of Jehovah of hosts, which he shakes over them.", "anderson": "", "haweis": "", "noyes": "In that day shall the Egyptians be like women; They shall tremble and fear On account of the shaking of the hand of Jehovah of hosts, Which he shall shake against them.", "webster": "In that day shall Egypt be like women: and it shall be afraid and fear because of the shaking of the hand of the LORD of hosts, which he shaketh over it.", "vulgate": "in die illa erit Aegyptus quasi mulieres et stupebunt et timebunt a facie commotionis manus Domini exercituum quam ipse movebit super eam;", "brenton": "But in that day the Egyptians shall be as women, in fear and in trembling because of the hand of the Lord of hosts, which he shall bring upon them."}}, {"v": 17, "ref": "19:17", "o": "וְ֠/הָיְתָה אַדְמַ֨ת יְהוּדָ֤ה לְ/מִצְרַ֨יִם֙ לְ/חָגָּ֔א כֹּל֩ אֲשֶׁ֨ר יַזְכִּ֥יר אֹתָ֛/הּ אֵלָ֖י/ו יִפְחָ֑ד מִ/פְּנֵ֗י עֲצַת֙ יְהוָ֣ה צְבָא֔וֹת אֲשֶׁר ה֖וּא יוֹעֵ֥ץ עָלָֽי/ו", "en": {"kjv": "And the land of Judah shall be a terror unto Egypt, every one that maketh mention thereof shall be afraid in himself, because of the counsel of the Lord of hosts, which he hath determined against it.", "web": "The land of Judah will become a terror to Egypt. Everyone to whom mention is made of it will be afraid, because of the plans of Yahweh of Armies, which he determines against it.", "bsb": "The land of Judah will bring terror to Egypt; whenever Judah is mentioned, Egypt will tremble over what the LORD of Hosts has planned against it.", "asv": "And the land of Judah shall become a terror unto Egypt; every one to whom mention is made thereof shall be afraid, because of the purpose of Jehovah of hosts, which he purposeth against it.", "ylt": "And the land of Judah hath been to Egypt for a cause of staggering, Every one who doth mention it, for himself feareth, Because of the counsel of Jehovah of Hosts, That He is counselling against it.", "dra": "And the land of Juda shall be a terror to Egypt: everyone that shall remember it shall tremble because of the counsel of the Lord of hosts, which he hath determined concerning it.", "bbe": "And the land of Judah will become a cause of great fear to Egypt; whenever its name comes to mind, Egypt will be in fear before the Lord of armies because of his purpose against it.", "geneva": "And the land of Iudah shall be a feare vnto Egypt: euery one that maketh mention of it, shalbe afraid thereat, because of ye counsell of the Lord of hostes, which he hath determined vpon it.", "wycliffe": "And the lond of Juda schal be to Egipt in to drede; ech that schal thenke on it, schal drede of the face of the counsel of the Lord of oostis, whiche he thouyte on it.", "rotherham": "Then shall the soil of Judah become, to Egypt, a terror; Every one to whom it is mentioned, will tremble,—Because of the purpose of Yahweh of hosts, which he is purposing against it.", "darby": "And the land of Judah shall be a dismay unto Egypt: every one that thinketh of it shall be afraid for himself, because of the counsel of Jehovah of hosts, which he hath purposed against it.", "twenty": "", "jps": "And the land of Judah shall become a terror unto Egypt, whensoever one maketh mention thereof to it; it shall be afraid, because of the purpose of HaShem of hosts, which He purposeth against it.", "acv": "And the land of Judah shall become a terror to Egypt. Everyone to whom mention is made of it shall be afraid because of the purpose of Jehovah of hosts, which he purposes against it.", "anderson": "", "haweis": "", "noyes": "The land of Judah shall be a terror to Egypt; Every one to whom it is mentioned shall tremble On account of the purpose of Jehovah of hosts, Which he hath determined against them.", "webster": "And the land of Judah shall be a terror to Egypt, every one that maketh mention of it shall be afraid in himself, because of the counsel of the LORD of hosts, which he hath determined against it.", "vulgate": "et erit terra Iuda Aegypto in festivitatem omnis qui illius fuerit recordatus pavebit a facie consilii Domini exercituum quod ipse cogitavit super eam;", "brenton": "And the land of the Jews shall be for a terror to the Egyptians: whosoever shall name it to them, they shall fear, because of the counsel which the Lord of hosts has purposed concerning it."}}, {"v": 18, "ref": "19:18", "o": "בַּ/יּ֣וֹם הַ/ה֡וּא יִהְיוּ֩ חָמֵ֨שׁ עָרִ֜ים בְּ/אֶ֣רֶץ מִצְרַ֗יִם מְדַבְּרוֹת֙ שְׂפַ֣ת כְּנַ֔עַן וְ/נִשְׁבָּע֖וֹת לַ/יהוָ֣ה צְבָא֑וֹת עִ֣יר הַ/הֶ֔רֶס יֵאָמֵ֖ר לְ/אֶחָֽת", "en": {"kjv": "In that day shall five cities in the land of Egypt speak the language of Canaan, and swear to the Lord of hosts; one shall be called, The city of destruction.", "web": "In that day, there will be five cities in the land of Egypt that speak the language of Canaan, and swear to Yahweh of Armies. One will be called “The city of destruction.”", "bsb": "In that day five cities in the land of Egypt will speak the language of Canaan and swear allegiance to the LORD of Hosts. One of them will be called the City of the Sun.", "asv": "In that day there shall be five cities in the land of Egypt that speak the language of Canaan, and swear to Jehovah of hosts; one shall be called The city of destruction.", "ylt": "In that day there are five cities in the land of Egypt, Speaking the lip of Canaan, And swearing to Jehovah of Hosts, `The city of destruction,' is said of one.", "dra": "In that day there shall be five cities in the land of Egypt, speaking the language of Chanaan, and swearing by the Lord of hosts: one shall be called the city of the sun.", "bbe": "In that day there will be five towns in the land of Egypt using the language of Canaan, and making oaths to the Lord of armies; and one of them will be named, The Town of the Sun.", "geneva": "In that day shall fiue cities in the lande of Egypt speake the language of Canaan, and shall sweare by the Lord of hostes. one shall be called the citie of destruction.", "wycliffe": "In that dai fyue citees schulen be in the lond of Egipt, and schulen speke with the tunge of Canaan, and schulen swere bi the Lord of oostis; the citee of the sunne schal be clepid oon.", "rotherham": "In that day, shall there be five cities in the land of Egypt Speaking the language of Canaan, And swearing unto Yahweh of hosts,—The city of destruction, shall be the name of one!", "darby": "In that day shall there be five cities in the land of Egypt speaking the language of Canaan, and swearing by Jehovah of hosts: one shall be called, The city of Heres.", "twenty": "", "jps": "In that day there shall be five cities in the land of Egypt that speak the language of Canaan, and swear to HaShem of hosts; one shall be called The city of destruction.", "acv": "In that day there shall be five cities in the land of Egypt that speak the language of Canaan, and swear to Jehovah of hosts. One shall be called The city of destruction.", "anderson": "", "haweis": "", "noyes": "In that day there shall be five cities in the land of Egypt Speaking the language of Canaan, And swearing by Jehovah of hosts; One of them shall be called the City of the Sun.", "webster": "In that day shall five cities in the land of Egypt speak the language of Canaan, and swear to the LORD of hosts; one shall be called, The city of destruction.", "vulgate": "in die illa erunt quinque civitates in terra Aegypti loquentes lingua Chanaan et iurantes per Dominum exercituum civitas Solis vocabitur una;", "brenton": "In that day there shall be five cities in Egypt speaking the language of Chanaan, and swearing by the name of the Lord of hosts; one city shall be called the city of Asedec."}}, {"v": 19, "ref": "19:19", "o": "בַּ/יּ֣וֹם הַ/ה֗וּא יִֽהְיֶ֤ה מִזְבֵּ֨חַ֙ לַֽ/יהוָ֔ה בְּ/ת֖וֹךְ אֶ֣רֶץ מִצְרָ֑יִם וּ/מַצֵּבָ֥ה אֵֽצֶל גְּבוּלָ֖/הּ לַֽ/יהוָֽה", "en": {"kjv": "In that day shall there be an altar to the Lord in the midst of the land of Egypt, and a pillar at the border thereof to the Lord.", "web": "In that day, there will be an altar to Yahweh in the midst of the land of Egypt, and a pillar to Yahweh at its border.", "bsb": "In that day there will be an altar to the LORD in the center of the land of Egypt, and a pillar to the LORD near her border.", "asv": "In that day shall there be an altar to Jehovah in the midst of the land of Egypt, and a pillar at the border thereof to Jehovah.", "ylt": "In that day there is an altar to Jehovah In the midst of the land of Egypt, And a standing pillar near its border to Jehovah,", "dra": "In that day there shall be an altar of the Lord in the midst of the land of Egypt, and a monument of the Lord at the borders thereof:", "bbe": "In that day there will be an altar to the Lord in the middle of the land of Egypt, and a pillar to the Lord at the edge of the land.", "geneva": "In that day shall the altar of the Lord be in the middes of the land of Egypt, and a pillar by the border thereof vnto the Lord.", "wycliffe": "In that dai the auter of the Lord schal be in the myddis of the lond of Egipt, and the title of the Lord schal be bisidis the ende therof;", "rotherham": "In that day, shall there be An altar unto Yahweh, in the midst of the land of Egypt,—And a pillar near the boundary thereof unto Yahweh;", "darby": "In that day shall there be an altar to Jehovah in the midst of the land of Egypt, and a pillar at the border thereof to Jehovah:", "twenty": "", "jps": "In that day shall there be an altar to HaShem in the midst of the land of Egypt, and a pillar at the border thereof to HaShem.", "acv": "In that day shall there be an altar to Jehovah in the midst of the land of Egypt, and a pillar to Jehovah at the border of it.", "anderson": "", "haweis": "", "noyes": "In that day there shall be an altar to Jehovah in the midst of the land of Egypt, And in the border of it a pillar to Jehovah,", "webster": "In that day shall there be an altar to the LORD in the midst of the land of Egypt, and a pillar at its border to the LORD.", "vulgate": "in die illa erit altare Domini in medio terrae Aegypti et titulus iuxta terminum eius Domini;", "brenton": "In that day there shall be an altar to the Lord in the land of the Egyptians, and a pillar to the Lord by its border."}}, {"v": 20, "ref": "19:20", "o": "וְ/הָיָ֨ה לְ/א֥וֹת וּ/לְ/עֵ֛ד לַֽ/יהוָ֥ה צְבָא֖וֹת בְּ/אֶ֣רֶץ מִצְרָ֑יִם כִּֽי יִצְעֲק֤וּ אֶל יְהוָה֙ מִ/פְּנֵ֣י לֹֽחֲצִ֔ים וְ/יִשְׁלַ֥ח לָ/הֶ֛ם מוֹשִׁ֥יעַ וָ/רָ֖ב וְ/הִצִּילָֽ/ם", "en": {"kjv": "And it shall be for a sign and for a witness unto the Lord of hosts in the land of Egypt: for they shall cry unto the Lord because of the oppressors, and he shall send them a saviour, and a great one, and he shall deliver them.", "web": "It will be for a sign and for a witness to Yahweh of Armies in the land of Egypt; for they will cry to Yahweh because of oppressors, and he will send them a savior and a defender, and he will deliver them.", "bsb": "It will be a sign and a witness to the LORD of Hosts in the land of Egypt. When they cry out to the LORD because of their oppressors, He will send them a savior and defender to rescue them.", "asv": "And it shall be for a sign and for a witness unto Jehovah of hosts in the land of Egypt; for they shall cry unto Jehovah because of oppressors, and he will send them a saviour, and a defender, and he will deliver them.", "ylt": "And it hath been for a sign and for a testimony, To Jehovah of Hosts in the land of Egypt, For they cry unto Jehovah from the face of oppressors, And He sendeth to them a saviour, Even a great one, and hath delivered them.", "dra": "It shall be for a sign, and for a testimony to the Lord of hosts in the land of Egypt. For they shall cry to the Lord because of the oppressor, and he shall send them a Saviour and a defender to deliver them.", "bbe": "And it will be a sign and a witness to the Lord of armies in the land of Egypt: when they are crying out to the Lord because of their cruel masters, then he will send them a saviour and a strong one to make them free.", "geneva": "And it shall be for a signe and for a witnes vnto the Lord of hostes in the land of Egypt: for they shall crie vnto the Lord, because of the oppressers, and he shall send them a Sauiour and a great man, and shall deliuer them.", "wycliffe": "and it schal be in to a signe and witnessyng to the Lord of oostis, in the lond of Egipt. For thei schulen crie to the Lord fro the face of the troblere, and he schal sende a sauyour to hem, and a forfiytere, that schal delyuere hem.", "rotherham": "And it shall become a sign and a witness unto Yahweh of hosts in the land of Egypt,—For they will make outcry unto Yahweh, because of oppressors, That he would send them a saviour—and a great one Then will he deliver them.", "darby": "and it shall be for a sign and for a witness to Jehovah of hosts in the land of Egypt; for they shall cry unto Jehovah because of the oppressors, and he will send them a saviour and defender, who shall deliver them.", "twenty": "", "jps": "And it shall be for a sign and for a witness unto HaShem of hosts in the land of Egypt; for they shall cry unto HaShem because of the oppressors, and He will send them a saviour, and a defender, who will deliver them.", "acv": "And it shall be for a sign and for a witness to Jehovah of hosts in the land of Egypt. For they shall cry to Jehovah because of oppressors, and he will send them a savior, and a defender, and he will deliver them.", "anderson": "", "haweis": "", "noyes": "Which shall be a sign and a witness For Jehovah of hosts in the land of Egypt, That they cried to Jehovah on account of their oppressors, And he sent them a saviour, and a defender, who delivered them.", "webster": "And it shall be for a sign and for a witness to the LORD of hosts in the land of Egypt: for they shall cry to the LORD because of the oppressors, and he shall send them a savior, and a great one, and he shall deliver them.", "vulgate": "et erit in signum et in testimonium Domino exercituum in terra Aegypti clamabunt enim ad Dominum a facie tribulantis et mittet eis salvatorem et propugnatorem qui liberet eos;", "brenton": "And it shall be for a sign to the Lord for ever in the land of Egypt: for they shall presently cry to the Lord by reason of them that afflict them, and he shall send them a man who shall save them; he shall judge and save them."}}, {"v": 21, "ref": "19:21", "o": "וְ/נוֹדַ֤ע יְהוָה֙ לְ/מִצְרַ֔יִם וְ/יָדְע֥וּ מִצְרַ֛יִם אֶת יְהוָ֖ה בַּ/יּ֣וֹם הַ/ה֑וּא וְ/עָֽבְדוּ֙ זֶ֣בַח וּ/מִנְחָ֔ה וְ/נָדְרוּ נֵ֥דֶר לַֽ/יהוָ֖ה וְ/שִׁלֵּֽמוּ", "en": {"kjv": "And the Lord shall be known to Egypt, and the Egyptians shall know the Lord in that day, and shall do sacrifice and oblation; yea, they shall vow a vow unto the Lord, and perform it.", "web": "Yahweh will be known to Egypt, and the Egyptians will know Yahweh in that day. Yes, they will worship with sacrifice and offering, and will vow a vow to Yahweh, and will perform it.", "bsb": "The LORD will make Himself known to Egypt, and on that day Egypt will acknowledge the LORD. They will worship with sacrifices and offerings; they will make vows to the LORD and fulfill them.", "asv": "And Jehovah shall be known to Egypt, and the Egyptians shall know Jehovah in that day; yea, they shall worship with sacrifice and oblation, and shall vow a vow unto Jehovah, and shall perform it.", "ylt": "And known hath been Jehovah to Egypt, And the Egyptians have known Jehovah in that day, And done sacrifice and present, And vowed a vow to Jehovah, and completed it .", "dra": "And the Lord shall be known by Egypt, and the Egyptians shall know the Lord in that day, and shall worship him with sacrifices and offerings: and they shall make vows to the Lord, and perform them.", "bbe": "And the Lord will give the knowledge of himself to Egypt, and the Egyptians will give honour to the Lord in that day; they will give him worship with offerings and meal offerings, and will take an oath to the Lord and give effect to it.", "geneva": "And the Lord shall be knowen of the Egyptians, and the Egyptians shall knowe the Lord in that day, and doe sacrifice and oblation, and shall vowe vowes vnto the Lord, and performe them.", "wycliffe": "And the Lord schal be knowun of Egipt, and Egipcians schulen knowe the Lord in that dai; and thei schulen worschipe hym in sacrifices and yiftis, and thei schulen make vowis to the Lord, and thei schulen paie.", "rotherham": "Then will, Yahweh, make himself known, to the Egyptians, So shall the Egyptians know, Yahweh, in that day,—And they will offer a sacrifice and a present And will vow a vow unto Yahweh and will perform.", "darby": "And Jehovah shall be known to the Egyptians, and the Egyptians shall know Jehovah in that day, and shall serve with sacrifice and oblation; and they shall vow a vow unto Jehovah, and perform it.", "twenty": "", "jps": "And HaShem shall make Himself known to Egypt, and the Egyptians shall know HaShem in that day; yea, they shall worship with sacrifice and offering, and shall vow a vow unto HaShem, and shall perform it.", "acv": "And Jehovah shall be known to Egypt, and the Egyptians shall know Jehovah in that day. Yea, they shall worship with sacrifice and oblation, and shall vow a vow to Jehovah, and shall perform it.", "anderson": "", "haweis": "", "noyes": "Thus shall Jehovah be made known to Egypt, And the Egyptians shall know Jehovah in that day, And shall offer him sacrifices and oblations; They shall make vows to Jehovah, and perform them.", "webster": "And the LORD shall be known to Egypt, and the Egyptians shall know the LORD in that day, and shall do sacrifice and oblation; yes, they shall vow a vow to the LORD, and perform [it].", "vulgate": "et cognoscetur Dominus ab Aegypto et cognoscent Aegyptii Dominum in die illa et colent eum in hostiis et muneribus et vota vovebunt Domino et solvent;", "brenton": "And the Lord shall be known to the Egyptians, and the Egyptians shall know the Lord in that day; and they shall offer sacrifices, and shall vow vows to the Lord, and pay them."}}, {"v": 22, "ref": "19:22", "o": "וְ/נָגַ֧ף יְהוָ֛ה אֶת מִצְרַ֖יִם נָגֹ֣ף וְ/רָפ֑וֹא וְ/שָׁ֨בוּ֙ עַד יְהוָ֔ה וְ/נֶעְתַּ֥ר לָ/הֶ֖ם וּ/רְפָאָֽ/ם", "en": {"kjv": "And the Lord shall smite Egypt: he shall smite and heal it: and they shall return even to the Lord, and he shall be intreated of them, and shall heal them.", "web": "Yahweh will strike Egypt, striking and healing. They will return to Yahweh, and he will be entreated by them, and will heal them.", "bsb": "And the LORD will strike Egypt with a plague; He will strike them but heal them. They will turn to the LORD, and He will hear their prayers and heal them.", "asv": "And Jehovah will smite Egypt, smiting and healing; and they shall return unto Jehovah, and he will be entreated of them, and will heal them.", "ylt": "And Jehovah hath smitten Egypt, smiting and healing, And they have turned back unto Jehovah, And He hath been entreated of them, And hath healed them.", "dra": "And the Lord shall strike Egypt with a scourge, and shall heal it, and they shall return to the Lord, and he shall be pacified towards them, and heal them.", "bbe": "And the Lord will send punishment on Egypt, and will make them well again; and when they come back to the Lord he will give ear to their prayer and take away their disease.", "geneva": "So ye Lord shall smite Egypt, he shall smite and heale it: for he shall returne vnto ye Lord, and he shall be intreated of them and shall heale them.", "wycliffe": "And the Lord schal smyte Egipt with a wounde, and schal make it hool; and Egipcians schulen turne ayen to the Lord, and he schal be plesid in hem, and he schal make hem hool.", "rotherham": "And Yahweh, will plague Egypt, plague and heal,—And they will turn unto Yahweh And he will be entreated of them and will heal them.", "darby": "And Jehovah will smite Egypt; he will smite and heal: and they shall return to Jehovah, and he will be entreated of them, and will heal them.", "twenty": "", "jps": "And HaShem will smite Egypt, smiting and healing; and they shall return unto HaShem, and He will be entreated of them, and will heal them.", "acv": "And Jehovah will smite Egypt, smiting and healing, and they shall return to Jehovah. And he will be entreated by them, and will heal them.", "anderson": "", "haweis": "", "noyes": "Thus Jehovah will smite Egypt; he will smite and heal her; They shall return to Jehovah; Therefore will he hear and heal them.", "webster": "And the LORD will smite Egypt: he will smite and heal [it]: and they shall return [even] to the LORD, and he will be entreated by them, and will heal them.", "vulgate": "et percutiet Dominus Aegyptum plaga et sanabit eam et revertentur ad Dominum et placabitur eis et sanabit eos;", "brenton": "And the Lord shall smite the Egyptians with a stroke, and shall completely heal them: and they shall return to the Lord, and he shall hear them, and thoroughly heal them."}}, {"v": 23, "ref": "19:23", "o": "בַּ/יּ֣וֹם הַ/ה֗וּא תִּהְיֶ֨ה מְסִלָּ֤ה מִ/מִּצְרַ֨יִם֙ אַשּׁ֔וּרָ/ה וּ/בָֽא אַשּׁ֥וּר בְּ/מִצְרַ֖יִם וּ/מִצְרַ֣יִם בְּ/אַשּׁ֑וּר וְ/עָבְד֥וּ מִצְרַ֖יִם אֶת אַשּֽׁוּר", "en": {"kjv": "In that day shall there be a highway out of Egypt to Assyria, and the Assyrian shall come into Egypt, and the Egyptian into Assyria, and the Egyptians shall serve with the Assyrians.", "web": "In that day there will be a highway out of Egypt to Assyria, and the Assyrian shall come into Egypt, and the Egyptian into Assyria; and the Egyptians will worship with the Assyrians.", "bsb": "In that day there will be a highway from Egypt to Assyria. The Assyrians will go to Egypt, and the Egyptians to Assyria. The Egyptians and Assyrians will worship together.", "asv": "In that day shall there be a highway out of Egypt to Assyria, and the Assyrian shall come into Egypt, and the Egyptian into Assyria; and the Egyptians shall worship with the Assyrians.", "ylt": "In that day is a highway out of Egypt to Asshur, And come in have the Assyrians to Egypt, And the Egyptians into Asshur, And the Egyptians have served with the Assyrians.", "dra": "In that day there shall be a way from Egypt to the Assyrians, and the Assyrian shall enter into Egypt, and the Egyptian to the Assyrians, and the Egyptians shall serve the Assyrian.", "bbe": "In that day there will be a highway out of Egypt to Assyria, and Assyria will come into Egypt, and Egypt will come into Assyria; and the Egyptians will give worship to the Lord together with the Assyrians.", "geneva": "In that day shall there be a path from Egypt to Asshur, and Asshur shall come into Egypt, and Egypt into Asshur: so the Egyptians shall worship with Asshur.", "wycliffe": "In that dai a wei schal be fro Egipt in to Assiriens, and Egipcians schulen serue Assur; and Assur schal entre in to Egipt, and Egipt in to Assiriens.", "rotherham": "In that day, shall there be a highway. from Egypt to Assyria, And, the Assyrians, shall come into Egypt, And, the Egyptians, into Assyria; And, the Egyptians shall serve, with the Assyrians.", "darby": "In that day shall there be a highway out of Egypt to Assyria; and the Assyrian shall come into Egypt, and the Egyptian into Assyria; and Egypt shall serve with Assyria.", "twenty": "", "jps": "In that day shall there be a highway out of Egypt to Assyria, and the Assyrian shall come into Egypt, and the Egyptian into Assyria; and the Egyptians shall worship with the Assyrians.", "acv": "In that day there shall be a highway out of Egypt to Assyria. And the Assyrian shall come into Egypt, and the Egyptian into Assyria, and the Egyptians shall worship with the Assyrians.", "anderson": "", "haweis": "", "noyes": "In that day shall there he a highway from Egypt to Assyria, And the Assyrian shall come into Egypt, And the Egyptian into Assyria, And the Egyptians shall worship with the Assyrians.", "webster": "In that day shall there be a highway from Egypt to Assyria, and the Assyrian shall come into Egypt, and the Egyptian into Assyria, and the Egyptians shall serve with the Assyrians.", "vulgate": "in die illa erit via de Aegypto in Assyrios et intrabit Assyrius Aegyptum et Aegyptius in Assyrios et servient Aegyptii Assur;", "brenton": "In that day there shall be a way from Egypt to the Assyrians, and the Assyrians shall enter into Egypt, and the Egyptians shall go to the Assyrians, and the Egyptians shall serve the Assyrians."}}, {"v": 24, "ref": "19:24", "o": "בַּ/יּ֣וֹם הַ/ה֗וּא יִהְיֶ֤ה יִשְׂרָאֵל֙ שְׁלִ֣ישִׁיָּ֔ה לְ/מִצְרַ֖יִם וּ/לְ/אַשּׁ֑וּר בְּרָכָ֖ה בְּ/קֶ֥רֶב הָ/אָֽרֶץ", "en": {"kjv": "In that day shall Israel be the third with Egypt and with Assyria, even a blessing in the midst of the land:", "web": "In that day, Israel will be the third with Egypt and with Assyria, a blessing in the midst of the earth;", "bsb": "In that day Israel will join a three-party alliance with Egypt and Assyria—a blessing upon the earth.", "asv": "In that day shall Israel be the third with Egypt and with Assyria, a blessing in the midst of the earth;", "ylt": "In that day is Israel third, After Egypt, and after Asshur, A blessing in the heart of the earth.", "dra": "In that day shall Israel be the third to the Egyptian and the Assyrian: a blessing in the midst of the land,", "bbe": "In that day Israel will be the third together with Egypt and Assyria, a blessing in the earth:", "geneva": "In that day shall Israel be the third with Egypt and Asshur, euen a blessing in the middes of the land.", "wycliffe": "In that dai Israel schal be the thridde to Egipt and to Assur, the blessyng in the myddil of erthe;", "rotherham": "In that day, shall, Israel, be, a third, with Egypt and with Assyria,—A blessing in the midst of the earth:", "darby": "In that day shall Israel be the third with Egypt and with Assyria, a blessing in the midst of the earth;", "twenty": "", "jps": "In that day shall Israel be the third with Egypt and with Assyria, a blessing in the midst of the earth;", "acv": "In that day Israel shall be the third with Egypt and with Assyria, a blessing in the midst of the earth,", "anderson": "", "haweis": "", "noyes": "In that day shall Israel be the third In connection with Egypt and Assyria, A blessing in the midst of the earth.", "webster": "In that day shall Israel be the third with Egypt and with Assyria, [even] a blessing in the midst of the land:", "vulgate": "in die illa erit Israhel tertius Aegyptio et Assyrio benedictio in medio terrae;", "brenton": "In that day shall Israel be third with the Egyptians and the Assyrians, blessed in the land which the Lord of hosts has blessed,"}}, {"v": 25, "ref": "19:25", "o": "אֲשֶׁ֧ר בֵּרֲכ֛/וֹ יְהוָ֥ה צְבָא֖וֹת לֵ/אמֹ֑ר בָּר֨וּךְ עַמִּ֜/י מִצְרַ֗יִם וּ/מַעֲשֵׂ֤ה יָדַ/י֙ אַשּׁ֔וּר וְ/נַחֲלָתִ֖/י יִשְׂרָאֵֽל", "en": {"kjv": "Whom the Lord of hosts shall bless, saying, Blessed be Egypt my people, and Assyria the work of my hands, and Israel mine inheritance.", "web": "because Yahweh of Armies has blessed them, saying, “Blessed be Egypt my people, Assyria the work of my hands, and Israel my inheritance.”", "bsb": "The LORD of Hosts will bless them, saying, “Blessed be Egypt My people, Assyria My handiwork, and Israel My inheritance.”", "asv": "for that Jehovah of hosts hath blessed them, saying, Blessed be Egypt my people, and Assyria the work of my hands, and Israel mine inheritance.", "ylt": "In that Jehovah of Hosts did bless it, saying, `Blessed is My people--Egypt, And the work of My hands--Asshur, And Mine inheritance--Israel!'", "dra": "Which the Lord of hosts hath blessed, saying: Blessed be my people of Egypt, and the work of my hands to the Assyrian: but Israel is my inheritance.", "bbe": "Because of the blessing of the Lord of armies which he has given them, saying, A blessing on Egypt my people, and on Assyria the work of my hands, and on Israel my heritage.", "geneva": "For the Lord of hostes shall blesse it, saying, Blessed be my people Egypt and Asshur, the worke of mine hands, and Israel mine inheritance.", "wycliffe": "whom the Lord of oostis blesside, seiynge, Blessid be my puple of Egipt, and the werk of myn hondis be to Assiriens; but myne eritage be to Israel.", "rotherham": "Whom Yahweh of hosts hath blessed saying,—Blessed, be My people—the Egyptians, And the work of my hands—the Assyrians, And mine own inheritance—Israel.", "darby": "whom Jehovah of hosts will bless, saying, Blessed be Egypt my people, and Assyria the work of my hands, and Israel mine inheritance!", "twenty": "", "jps": "for that HaShem of hosts hath blessed him, saying: 'Blessed be Egypt My people and Assyria the work of My hands, and Israel Mine inheritance.'", "acv": "in that Jehovah of hosts has blessed them, saying, Blessed be Egypt my people, and Assyria the work of my hands, and Israel my inheritance.", "anderson": "", "haweis": "", "noyes": "Jehovah of hosts shall bless them, and say, Blessed be Egypt, my people, And Assyria, the work of my hands, And Israel, my inheritance!", "webster": "Whom the LORD of hosts will bless, saying, Blessed [be] Egypt my people, and Assyria the work of my hands, and Israel my inheritance.", "vulgate": "cui benedixit Dominus exercituum dicens benedictus populus meus Aegypti et opus manuum mearum Assyrio hereditas autem mea Israhel;", "brenton": "saying, Blessed be my people that is in Egypt, and that is among the Assyrians, and Israel mine inheritance."}}]}, {"c": 20, "verses": [{"v": 1, "ref": "20:1", "o": "בִּ/שְׁנַ֨ת בֹּ֤א תַרְתָּן֙ אַשְׁדּ֔וֹדָ/ה בִּ/שְׁלֹ֣ח אֹת֔/וֹ סַֽרְג֖וֹן מֶ֣לֶךְ אַשּׁ֑וּר וַ/יִּלָּ֥חֶם בְּ/אַשְׁדּ֖וֹד וַֽ/יִּלְכְּדָֽ/הּ", "en": {"kjv": "In the year that Tartan came unto Ashdod, (when Sargon the king of Assyria sent him,) and fought against Ashdod, and took it;", "web": "In the year that Tartan came to Ashdod, when Sargon the king of Assyria sent him, and he fought against Ashdod and took it;", "bsb": "Before the year that the chief commander, sent by Sargon king of Assyria, came to Ashdod and attacked and captured it,", "asv": "In the year that Tartan came unto Ashdod, when Sargon the king of Assyria sent him, and he fought against Ashdod and took it;", "ylt": "In the year of the coming in of Tartan to Ashdod, when Sargon king of Asshur sendeth him, and he fighteth against Ashdod, and captureth it,", "dra": "In the year that Tharthan entered into Azotus, when Sargon the king of the Assyrians had sent him, and he had fought against Azotus, and had taken it:", "bbe": "In the year when the Tartan came to Ashdod, sent by Sargon, king of Assyria, and made war against it and took it;", "geneva": "In the yeere that Tartan came to Ashdod, (when Sargon King of Asshur sent him) and had fought against Ashdod, and taken it,", "wycliffe": "In the yeer wherynne Tharthan entride in to Azotus, whanne Sargon, the kyng of Assiriens, hadde sent hym, and he hadde fouyte ayens Azotus, and hadde take it;", "rotherham": "In the year that Tartan entered Ashdod, when Sargon king of Assyria, sent him,—and he fought against Ashdod and captured it,—", "darby": "In the year that Tartan came to Ashdod, when Sargon the king of Assyria sent him, (and he fought against Ashdod and took it,)", "twenty": "", "jps": "In the year that Tartan came into Ashdod, when Sargon the king of Assyria sent him, and he fought against Ashdod and took it;", "acv": "In the year that Tartan came to Ashdod, when Sargon the king of Assyria sent him, and he fought against Ashdod and took it,", "anderson": "", "haweis": "", "noyes": "In the year in which Tartan, being sent by Sargon, the king of Assyria, came to Ashdod, and fought against Ashdod, and took it,", "webster": "In the year that Tartan came to Ashdod, (when Sargon the king of Assyria sent him,) and fought against Ashdod, and took it;", "vulgate": "in anno quo ingressus est Tharthan in Azotum cum misisset eum Sargon rex Assyriorum et pugnasset contra Azotum et cepisset eam;", "brenton": "In the year when Tanathan came to Azotus, when he was sent by Arna king of the Assyrians, and warred against Azotus, and took it;"}}, {"v": 2, "ref": "20:2", "o": "בָּ/עֵ֣ת הַ/הִ֗יא דִּבֶּ֣ר יְהוָה֮ בְּ/יַ֣ד יְשַׁעְיָ֣הוּ בֶן אָמוֹץ֮ לֵ/אמֹר֒ לֵ֗ךְ וּ/פִתַּחְתָּ֤ הַ/שַּׂק֙ מֵ/עַ֣ל מָתְנֶ֔י/ךָ וְ/נַעַלְ/ךָ֥ תַחֲלֹ֖ץ מֵ/עַ֣ל רַגְלֶ֑י/ךָ וַ/יַּ֣עַשׂ כֵּ֔ן הָלֹ֖ךְ עָר֥וֹם וְ/יָחֵֽף", "en": {"kjv": "At the same time spake the Lord by Isaiah the son of Amoz, saying, Go and loose the sackcloth from off thy loins, and put off thy shoe from thy foot. And he did so, walking naked and barefoot.", "web": "at that time Yahweh spoke by Isaiah the son of Amoz, saying, “Go, and loosen the sackcloth from off your waist, and take your shoes from off your feet.” He did so, walking naked and barefoot.", "bsb": "the LORD had already spoken through Isaiah son of Amoz, saying, “Go, remove the sackcloth from your waist and the sandals from your feet.” And Isaiah did so, walking around naked and barefoot.", "asv": "at that time Jehovah spake by Isaiah the son of Amoz, saying, Go, and loose the sackcloth from off thy loins, and put thy shoe from off thy foot. And he did so, walking naked and barefoot.", "ylt": "at that time spake Jehovah by the hand of Isaiah son of Amoz, saying, `Go, and thou hast loosed the sackcloth from off thy loins, and thy sandal thou dost draw from off thy foot,' and he doth so, going naked and barefoot.", "dra": "At that same time the Lord spoke by the hand of Isaiah the son of Amos, saying Go, and loose the sackcloth from off thy loins, and take off thy shoes from thy feet. And he did so, and went naked, and barefoot.", "bbe": "At that time the word of the Lord came to Isaiah, the son of Amoz, saying, Go, and take off your robe, and your shoes from your feet; and he did so, walking unclothed and without shoes on his feet.", "geneva": "At the same time spake the Lord by ye hand of Isaiah the sonne of Amoz, saying, Goe, and loose the sackecloth from thy loynes, and put off thy shooe from thy foote. And he did so, walking naked and barefoote.", "wycliffe": "in that tyme the Lord spak in the hond of Isaye, the sone of Amos, and seide, Go thou, and vnbynde the sak fro thi leendis, and take awei thi schoon fro thi feet. And he dide so, goynge nakid and vnschood.", "rotherham": "At that time, spake Yahweh, through Isaiah son of Amoz, saying, Go, and loose the sackcloth from off thy loins, And thy sandal, draw thou off from thy foot,—And he did so, walking disrobed and barefoot.", "darby": "at that time spoke Jehovah by Isaiah the son of Amoz, saying, Go and loose the sackcloth from off thy loins, and put off thy sandal from thy foot. And he did so, walking naked and barefoot.", "twenty": "", "jps": "at that time HaShem spoke by Isaiah the son of Amoz, saying: 'Go, and loose the sackcloth from off thy loins, and put thy shoe from off thy foot.' And he did so, walking naked and barefoot.", "acv": "at that time Jehovah spoke by Isaiah the son of Amoz, saying, Go, and loose the sackcloth from off thy loins, and put thy shoe from off thy foot. And he did so, walking naked and barefoot.", "anderson": "", "haweis": "", "noyes": "at that time spake Jehovah through Isaiah the son of Amoz in this manner: Go, and loose the sackcloth from thy loins, and put off thy shoes from thy feet. And he did so, walking naked and barefoot.", "webster": "At the same time spoke the LORD by Isaiah the son of Amoz, saying, Go, and loose the sackcloth from off thy loins, and put off thy shoe from thy foot. And he did so, walking naked and barefoot.", "vulgate": "in tempore illo locutus est Dominus in manu Isaiae filii Amos dicens vade et solve saccum de lumbis tuis et calciamenta tua tolle de pedibus tuis et fecit sic vadens nudus et disculciatus;", "brenton": "then the Lord spoke to Esaias the son of Amos, saying, Go and take the sackcloth off thy loins, and loose thy sandals from off thy feet, and do thus, going naked and barefoot."}}, {"v": 3, "ref": "20:3", "o": "וַ/יֹּ֣אמֶר יְהוָ֔ה כַּ/אֲשֶׁ֥ר הָלַ֛ךְ עַבְדִּ֥/י יְשַׁעְיָ֖הוּ עָר֣וֹם וְ/יָחֵ֑ף שָׁלֹ֤שׁ שָׁנִים֙ א֣וֹת וּ/מוֹפֵ֔ת עַל מִצְרַ֖יִם וְ/עַל כּֽוּשׁ", "en": {"kjv": "And the Lord said, Like as my servant Isaiah hath walked naked and barefoot three years for a sign and wonder upon Egypt and upon Ethiopia;", "web": "Yahweh said, “As my servant Isaiah has walked naked and barefoot three years for a sign and a wonder concerning Egypt and concerning Ethiopia,", "bsb": "Then the LORD said, “Just as My servant Isaiah has gone naked and barefoot for three years as a sign and omen against Egypt and Cush,", "asv": "And Jehovah said, Like as my servant Isaiah hath walked naked and barefoot three years for a sign and a wonder concerning Egypt and concerning Ethiopia;", "ylt": "And Jehovah saith, `As My servant Isaiah hath gone naked and barefoot three years, a sign and a wonder for Egypt and for Cush,", "dra": "And the Lord said: As my servant Isaiah hath walked, naked and barefoot, it shall be a sign and a wonder of three years upon Egypt, and upon Ethiopia,", "bbe": "And the Lord said, As my servant Isaiah has gone unclothed and without shoes for three years as a sign and a wonder to Egypt and Ethiopia,", "geneva": "And the Lord said, Like as my seruant Isaiah hath walked naked, and barefoote three yeeres, as a signe and wonder vpon Egypt, and Ethiopia,", "wycliffe": "And the Lord seide, As my seruaunt Ysaie yede nakid and vnschood, a signe and greet wondur of thre yeer schal be on Egipt, and on Ethiopie;", "rotherham": "Then said Yahweh,—As my servant Isaiah, hath walked, disrobed and barefoot three years as a sign and a wonder against Egypt and against Ethiopia,", "darby": "And Jehovah said, Like as my servant Isaiah hath walked naked and barefoot three years, a sign and a wonder concerning Egypt and concerning Ethiopia,", "twenty": "", "jps": "And HaShem said: 'Like as My servant Isaiah hath walked naked and barefoot to be for three years a sign and a wonder upon Egypt and upon Ethiopia,", "acv": "And Jehovah said, Just as my servant Isaiah has walked naked and barefoot three years for a sign and a wonder concerning Egypt and concerning Ethiopia,", "anderson": "", "haweis": "", "noyes": "And Jehovah said: As my servant Isaiah hath walked naked and barefoot three years, a sign and a token for Egypt and Ethiopia,", "webster": "And the LORD said, As my servant Isaiah hath walked naked and barefoot three years [for] a sign and wonder upon Egypt and upon Cush;", "vulgate": "et dixit Dominus sicut ambulavit servus meus Isaias nudus et disculciatus trium annorum signum et portentum erit super Aegyptum et super Aethiopiam;", "brenton": "And the Lord said, As my servant Esaias has walked naked and barefoot three years, there shall be three years for signs and wonders to the Egyptians and Ethiopians;"}}, {"v": 4, "ref": "20:4", "o": "כֵּ֣ן יִנְהַ֣ג מֶֽלֶךְ אַ֠שּׁוּר אֶת שְׁבִ֨י מִצְרַ֜יִם וְ/אֶת גָּל֥וּת כּ֛וּשׁ נְעָרִ֥ים וּ/זְקֵנִ֖ים עָר֣וֹם וְ/יָחֵ֑ף וַ/חֲשׂוּפַ֥י שֵׁ֖ת עֶרְוַ֥ת מִצְרָֽיִם", "en": {"kjv": "So shall the king of Assyria lead away the Egyptians prisoners, and the Ethiopians captives, young and old, naked and barefoot, even with their buttocks uncovered, to the shame of Egypt.", "web": "so the king of Assyria will lead away the captives of Egypt and the exiles of Ethiopia, young and old, naked and barefoot, and with buttocks uncovered, to the shame of Egypt.", "bsb": "so the king of Assyria will lead away the captives of Egypt and the exiles of Cush, young and old alike, naked and barefoot, with bared buttocks—to Egypt’s shame.", "asv": "so shall the king of Assyria lead away the captives of Egypt, and the exiles of Ethiopia, young and old, naked and barefoot, and with buttocks uncovered, to the shame of Egypt.", "ylt": "so doth the king of Asshur lead the captivity of Egypt, and the removal of Cush, young and old, naked and barefoot, with seat uncovered--the nakedness of Egypt;", "dra": "So shall the king of the Assyrians lead away the prisoners of Egypt, and the captivity of Ethiopia, young and old, naked and barefoot, with their buttocks uncovered to the shame of Egypt.", "bbe": "So will the king of Assyria take away the prisoners of Egypt and those forced out of Ethiopia, young and old, unclothed and without shoes, and with backs uncovered, to the shame of Egypt.", "geneva": "So shall the King of Asshur take away the captiuitie of Egypt, and the captiuitie of Ethiopia, both yong men and olde men, naked and barefoote, with their buttockes vncouered, to the shame of Egypt.", "wycliffe": "so the kyng of Assiriens schal dryue the caitifte of Egipt, and the passyng ouer of Ethiopie, a yong man and an eld man, nakid and vnschood, with the buttokis vnhilid, to the schenschipe of Egipt.", "rotherham": "So, shall the king of Assyria lead away the captives of Egypt and the exiles of Ethiopia young and old disrobed and barefoot, with their persons behind Uncovered the shame of Egypt.", "darby": "so shall the king of Assyria lead away the captives of Egypt and the exiles of Ethiopia, young and old, naked and barefoot, and with buttocks uncovered, [to] the shame of Egypt.", "twenty": "", "jps": "so shall the king of Assyria lead away the captives of Egypt, and the exiles of Ethiopia, young and old, naked and barefoot, and with buttocks uncovered, to the shame of Egypt.", "acv": "so shall the king of Assyria lead away the captives of Egypt, and the exiles of Ethiopia, young and old, naked and barefoot, and with buttocks uncovered, to the shame of Egypt.", "anderson": "", "haweis": "", "noyes": "so shall the king of Assyria lead the captives of Egypt, and prisoners of Ethiopia, young and old, naked and barefoot, with their hind parts uncovered, to the shame of the Egyptians.", "webster": "So shall the king of Assyria lead away the Egyptians prisoners, and the Cushites captives, young and old, naked and barefoot, even with [their] hind-parts uncovered, to the shame of Egypt.", "vulgate": "sic minabit rex Assyriorum captivitatem Aegypti et transmigrationem Aethiopiae iuvenum et senum nudam et disculciatam discopertis natibus ignominiam Aegypti;", "brenton": "for thus shall the king of the Assyrians lead the captivity of Egypt and the Ethiopians, young men and old, naked and barefoot, having the shame of Egypt exposed."}}, {"v": 5, "ref": "20:5", "o": "וְ/חַתּ֖וּ וָ/בֹ֑שׁוּ מִ/כּוּשׁ֙ מַבָּטָ֔/ם וּ/מִן מִצְרַ֖יִם תִּפְאַרְתָּֽ/ם", "en": {"kjv": "And they shall be afraid and ashamed of Ethiopia their expectation, and of Egypt their glory.", "web": "They will be dismayed and confounded, because of Ethiopia their expectation, and of Egypt their glory.", "bsb": "Those who made Cush their hope and Egypt their boast will be dismayed and ashamed.", "asv": "And they shall be dismayed and confounded, because of Ethiopia their expectation, and of Egypt their glory.", "ylt": "and they have been affrighted and ashamed of Cush their confidence, and of Egypt their beauty,", "dra": "And they shall be afraid, and ashamed of Ethiopia their hope, and of Egypt their glory.", "bbe": "And they will be full of fear, and will no longer have faith in Ethiopia which was their hope, or in Egypt which was their glory.", "geneva": "And they shall feare, and be ashamed of Ethiopia their expectation, and of Egypt their glory.", "wycliffe": "And thei schulen drede, and schulen be schent of Ethiopie, her hope, and of Egipt, her glorie.", "rotherham": "Thus shall they be confounded and turn pale,—For Ethiopia, their expectation, and For Egypt their boast;", "darby": "And they shall be terrified and ashamed of Ethiopia their confidence, and of Egypt their boast.", "twenty": "", "jps": "And they shall be dismayed and ashamed, because of Ethiopia their expectation, and of Egypt their glory.", "acv": "And they shall be dismayed and confounded because of Ethiopia their confidence, and of Egypt their glory.", "anderson": "", "haweis": "", "noyes": "Then shall they be afraid and ashamed on account of Ethiopia their trust, and of Egypt their glory.", "webster": "And they shall be afraid and ashamed of Cush their expectation, and of Egypt their glory.", "vulgate": "et timebunt et confundentur ab Aethiopia spe sua et ab Aegypto gloria sua;", "brenton": "And the Egyptians being defeated shall be ashamed of the Ethiopians, in whom they had trusted; for they were their glory."}}, {"v": 6, "ref": "20:6", "o": "וְ֠/אָמַר יֹשֵׁ֨ב הָ/אִ֣י הַ/זֶּה֮ בַּ/יּ֣וֹם הַ/הוּא֒ הִנֵּה כֹ֣ה מַבָּטֵ֗/נוּ אֲשֶׁר נַ֤סְנוּ שָׁם֙ לְ/עֶזְרָ֔ה לְ/הִ֨נָּצֵ֔ל מִ/פְּנֵ֖י מֶ֣לֶךְ אַשּׁ֑וּר וְ/אֵ֖יךְ נִמָּלֵ֥ט אֲנָֽחְנוּ", "en": {"kjv": "And the inhabitant of this isle shall say in that day, Behold, such is our expectation, whither we flee for help to be delivered from the king of Assyria: and how shall we escape?", "web": "The inhabitants of this coast land will say in that day, ‘Behold, this is our expectation, where we fled for help to be delivered from the king of Assyria. And we, how will we escape?’”", "bsb": "And on that day the dwellers of this coastland will say, ‘See what has happened to our source of hope, those to whom we fled for help and deliverance from the king of Assyria! How then can we escape?’”", "asv": "And the inhabitant of this coast-land shall say in that day, Behold, such is our expectation, whither we fled for help to be delivered from the king of Assyria: and we, how shall we escape?", "ylt": "and the inhabitant of this isle hath said in that day--Lo, thus is our trust, Whither we have fled for help, To be delivered from the king of Asshur, And how do we escape--we?'", "dra": "And the inhabitants of this isle shall say in that day: Lo this was our hope, to whom we fled for help, to deliver us from the face of the king of the Assyrians: and how shall we be able to escape?", "bbe": "And those living by the sea will say in that day, See the fate of our hope to whom we went for help and salvation from the king of Assyria: what hope have we then of salvation?", "geneva": "Then shall the inhabitant of this yle say in that day, Behold, such is our expectation, whither we fledde for helpe to be deliuered from the King of Asshur, and howe shall we be deliuered?", "wycliffe": "And a dwellere of this ile schal seie in that dai, This was our hope, to which we fledden for help, that thei schulden delyuere vs fro the face of the kyng of Assiryens; and hou moun we ascape?", "rotherham": "And the inhabitant of this shore, shall exclaim, in that day, Lo! such, is our expectation, whereunto we fled for help, that we might be delivered from the presence of the king of Assyria! How then shall, we, escape?", "darby": "And the inhabitants of this coast shall say in that day, Behold, such is our confidence, whither we fled for help to be delivered from the king of Assyria; and how shall we escape?", "twenty": "", "jps": "And the inhabitant of this coast-land shall say in that day: Behold, such is our expectation, whither we fled for help to be delivered from the king of Assyria; and how shall we escape?'", "acv": "And the inhabitant of this coastland shall say in that day, Behold, such is our trust, where we fled for help to be delivered from the king of Assyria. And we, how shall we escape?", "anderson": "", "haweis": "", "noyes": "The inhabitant of this coast shall say in that day, \"Behold, so is it with them in whom we trusted, and to whom we fled for help, that we might be delivered from the king of Assyria. How then shall we escape?\"", "webster": "And the inhabitant of this isle shall say in that day, Behold, such [is] our expectation, whither we flee for help to be delivered from the king of Assyria: and how shall we escape?", "vulgate": "et dicet habitator insulae huius in die illa ecce haec erat spes nostra ad quos confugimus in auxilium ut liberaret nos a facie regis Assyriorum et quomodo effugere poterimus nos;", "brenton": "And they that dwell in this island shall say in that day, Behold, we trusted to flee to them for help, who could not save themselves from the king of the Assyrians: and how shall we be saved?"}}]}, {"c": 21, "verses": [{"v": 1, "ref": "21:1", "o": "מַשָּׂ֖א מִדְבַּר יָ֑ם כְּ/סוּפ֤וֹת בַּ/נֶּ֨גֶב֙ לַֽ/חֲלֹ֔ף מִ/מִּדְבָּ֣ר בָּ֔א מֵ/אֶ֖רֶץ נוֹרָאָֽה", "en": {"kjv": "The burden of the desert of the sea. As whirlwinds in the south pass through; so it cometh from the desert, from a terrible land.", "web": "The burden of the wilderness of the sea. As whirlwinds in the South sweep through, it comes from the wilderness, from an awesome land.", "bsb": "This is the burden against the Desert by the Sea: Like whirlwinds sweeping through the Negev, an invader comes from the desert, from a land of terror.", "asv": "The burden of the wilderness of the sea. As whirlwinds in the South sweep through, it cometh from the wilderness, from a terrible land.", "ylt": "The burden of the wilderness of the sea. `Like hurricanes in the south for passing through, From the wilderness it hath come, From a fearful land.", "dra": "The burden of the desert of the sea. As whirlwinds come from the south, it cometh from the desert from a terrible land.", "bbe": "The word about the waste land. As storm-winds in the South go rushing through, it comes from the waste land, from the land greatly to be feared.", "geneva": "The burden of the desert Sea. As the whirlewindes in the South vse to passe from the wildernesse, so shall it come from the horrible land.", "wycliffe": "The birthun of the forsakun see. As whirlewyndis comen fro the southwest, it cometh fro desert, fro the orible lond.", "rotherham": "The oracle on the desert of the sea: As storm-winds in the South which with a rush from the desert, do come from a terrible land,", "darby": "The burden of the desert of the sea. As whirlwinds in the south pass through, so it cometh from the desert, from a terrible land.", "twenty": "", "jps": "The burden of the wilderness of the sea. As whirlwinds in the South sweeping on, it cometh from the wilderness, from a dreadful land.", "acv": "The burden of the wilderness of the sea. As whirlwinds in the South sweep through, it comes from the wilderness, from a terrible land.", "anderson": "", "haweis": "", "noyes": "The prophecy concerning the desert of the sea. As storms which rush along through the south, So it cometh from the desert, From the terrible land.", "webster": "The burden of the desert of the sea. As whirlwinds in the south pass through; [so] it cometh from the desert, from a terrible land.", "vulgate": "onus deserti maris sicut turbines ab africo veniunt de deserto venit de terra horribili;", "brenton": "THE VISION OF THE DESERT. As though a whirlwind should pass through the desert, coming from a desert, even from such a land,"}}, {"v": 2, "ref": "21:2", "o": "חָז֥וּת קָשָׁ֖ה הֻגַּד לִ֑/י הַ/בּוֹגֵ֤ד בּוֹגֵד֙ וְ/הַ/שּׁוֹדֵ֣ד שׁוֹדֵ֔ד עֲלִ֤י עֵילָם֙ צוּרִ֣י מָדַ֔י כָּל אַנְחָתָ֖/ה הִשְׁבַּֽתִּי", "en": {"kjv": "A grievous vision is declared unto me; the treacherous dealer dealeth treacherously, and the spoiler spoileth. Go up, O Elam: besiege, O Media; all the sighing thereof have I made to cease.", "web": "A grievous vision is declared to me. The treacherous man deals treacherously, and the destroyer destroys. Go up, Elam; attack! I have stopped all of Media’s sighing.", "bsb": "A dire vision is declared to me: “The traitor still betrays, and the destroyer still destroys. Go up, O Elam! Lay siege, O Media! I will put an end to all her groaning.”", "asv": "A grievous vision is declared unto me; the treacherous man dealeth treacherously, and the destroyer destroyeth. Go up, O Elam; besiege, O Media; all the sighing thereof have I made to cease.", "ylt": "A hard vision hath been declared to me, The treacherous dealer is dealing treacherously, And the destroyer is destroying. Go up, O Elam, besiege, O Media, All its sighing I have caused to cease.", "dra": "A grievous vision is told me: he that is unfaithful dealeth unfaithfully: and he that is a spoiler, spoileth. Go up, O Elam, besiege, O Mede: I have made all the mourning thereof to cease.", "bbe": "A vision of fear comes before my eyes; the worker of deceit goes on in his false way, and the waster goes on making waste. Up! Elam; to the attack! Media; I have put an end to her sorrow.", "geneva": "A grieuous vision was shewed vnto me, The transgressour against a transgressour, and the destroyer against a destroyer. Goe vp Elam, besiege Media: I haue caused all the mourning thereof to cease.", "wycliffe": "An hard reuelacioun is teld to me; he that is vnfeithful, doith vnfeithfuli; and he that is a distriere, distrieth. Thou Helam, stie, and thou, Meda, biseche; Y made al the weilyng therof for to ceesse.", "rotherham": "[So] hath, a grievous vision, been told me:—the deceiver, is deceiving. And the spoiler, is spoiling, Go up, O Elam Besiege O Media, All the sighing she hath caused, have I made to cease.", "darby": "A grievous vision is declared unto me: the treacherous dealeth treacherously, and the spoiler spoileth. Go up, Elam! besiege, Media! All the sighing thereof have I made to cease.", "twenty": "", "jps": "A grievous vision is declared unto me: 'The treacherous dealer dealeth treacherously, and the spoiler spoileth. Go up, O Elam! besiege, O Media! All the sighing thereof have I made to cease.'", "acv": "A grievous vision is declared to me. The treacherous man deals treacherously, and the destroyer destroys. Go up, O Elam. Besiege, O Media, all the sighing of it I have made to cease.", "anderson": "", "haweis": "", "noyes": "A grievous vision was revealed to me; The plunderer plundereth, and the destroyer destroyeth. \"Go up, O Elam! Besiege, O Media! All sighing do I make to cease.\"", "webster": "A grievous vision is declared to me; the treacherous dealer dealeth treacherously, and the spoiler plundereth. Go up, O Elam: besiege, O Media; all her sighing have I made to cease.", "vulgate": "visio dura nuntiata est mihi qui incredulus est infideliter agit et qui depopulator est vastat ascende Aelam obside Mede omnem gemitum eius cessare feci;", "brenton": "so a fearful and a grievous vision was declared to me: he that is treacherous deals treacherously, the transgressor transgresses. The Elamites are upon me, and the ambassadors of the Persians come against me: now will I groan and comfort myself."}}, {"v": 3, "ref": "21:3", "o": "עַל כֵּ֗ן מָלְא֤וּ מָתְנַ/י֙ חַלְחָלָ֔ה צִירִ֣ים אֲחָז֔וּ/נִי כְּ/צִירֵ֖י יֽוֹלֵדָ֑ה נַעֲוֵ֣יתִי מִ/שְּׁמֹ֔עַ נִבְהַ֖לְתִּי מֵ/רְאֽוֹת", "en": {"kjv": "Therefore are my loins filled with pain: pangs have taken hold upon me, as the pangs of a woman that travaileth: I was bowed down at the hearing of it; I was dismayed at the seeing of it.", "web": "Therefore my thighs are filled with anguish. Pains have taken hold on me, like the pains of a woman in labor. I am in so much pain that I can’t hear. I so am dismayed that I can’t see.", "bsb": "Therefore my body is filled with anguish. Pain grips me, like the pains of a woman in labor. I am bewildered to hear, I am dismayed to see.", "asv": "Therefore are my loins filled with anguish; pangs have taken hold upon me, as the pangs of a woman in travail: I am pained so that I cannot hear; I am dismayed so that I cannot see.", "ylt": "Therefore filled have been my loins with great pain, Pangs have seized me as pangs of a travailing woman, I have been bent down by hearing, I have been troubled by seeing.", "dra": "Therefore are my loins filled with pain, anguish hath taken hold of me, as the anguish of a woman in labour: I fell down at the hearing of it, I was troubled at the seeing of it.", "bbe": "For this cause I am full of bitter grief; pains like the pains of a woman in childbirth have come on me: I am bent down with sorrow at what comes to my ears; I am shocked by what I see.", "geneva": "Therefore are my loynes filled with sorow: sorowes haue taken me as the sorowes of a woman that trauayleth: I was bowed downe when I heard it, and I was amased when I sawe it.", "wycliffe": "Therfor my leendis ben fillid with sorewe; angwische weldide me, as the angwisch of a womman trauelynge of child; Y felle doun, whanne Y herde; Y was disturblid, whanne Y siy.", "rotherham": "For this cause, are my loins filled with anguish, Pangs, have seized me, as the pangs of her that is giving birth,—I writhe so that I cannot hear, I tremble, so that I cannot see:", "darby": "Therefore are my loins filled with pain; anguish hath taken hold upon me, as the anguish of a woman in travail: I am bowed down so as not to hear, I am dismayed so as not to see.", "twenty": "", "jps": "Therefore are my loins filled with convulsion; pangs have taken hold upon me, as the pangs of a woman in travail; I am bent so that I cannot hear; I am affrighted so that I cannot see.", "acv": "Therefore my loins are filled with anguish. Pangs have taken hold upon me, as the pangs of a woman in travail. I am pained so that I cannot hear. I am dismayed so that I cannot see.", "anderson": "", "haweis": "", "noyes": "Therefore are my loins full of pain; Pangs have seized me, as the pangs of a woman in travail; For convulsions I cannot hear; For anguish I cannot see.", "webster": "Therefore are my loins filled with pain: pangs have taken hold upon me, as the pangs of a woman that travaileth: I was bowed down at the hearing [of it]; I was dismayed at the seeing [of it].", "vulgate": "propterea repleti sunt lumbi mei dolore angustia possedit me sicut angustia parientis corrui cum audirem conturbatus sum cum viderem;", "brenton": "Therefore are my loins filled with feebleness, and pangs have seized me as a travailing woman: I dealt wrongfully that I might not hear; I hasted that I might not see."}}, {"v": 4, "ref": "21:4", "o": "תָּעָ֣ה לְבָבִ֔/י פַּלָּצ֖וּת בִּֽעֲתָ֑תְ/נִי אֵ֚ת נֶ֣שֶׁף חִשְׁקִ֔/י שָׂ֥ם לִ֖/י לַ/חֲרָדָֽה", "en": {"kjv": "My heart panted, fearfulness affrighted me: the night of my pleasure hath he turned into fear unto me.", "web": "My heart flutters. Horror has frightened me. The twilight that I desired has been turned into trembling for me.", "bsb": "My heart falters; fear makes me tremble. The twilight of my desire has turned to horror.", "asv": "My heart fluttereth, horror hath affrighted me; the twilight that I desired hath been turned into trembling unto me.", "ylt": "Wandered hath my heart, trembling hath terrified me, The twilight of my desire He hath made a fear to me,", "dra": "My heart failed, darkness amazed me: Babylon my beloved is become a wonder to me.", "bbe": "My mind is wandering, fear has overcome me: the evening of my desire has been turned into shaking for me.", "geneva": "Mine heart failed: fearefulnesse troubled me: the night of my pleasures hath he turned into feare vnto me.", "wycliffe": "Myn herte fadide, derknessis astonieden me; Babiloyne, my derlyng, is set to me in to myracle.", "rotherham": "My heart fluttereth, A horror, terrifieth me,—My twilight of pleasure, hath he turned for me into a time of trembling.", "darby": "My heart panteth, horror affrighteth me: the night of my pleasure hath he turned into trembling unto me.", "twenty": "", "jps": "My heart is bewildered, terror hath overwhelmed me; the twilight that I longed for hath been turned for me into trembling.", "acv": "My heart flutters. Horror has frightened me. The twilight that I desired has been turned into trembling to me.", "anderson": "", "haweis": "", "noyes": "My heart panteth, Terror hath seized upon me; The evening of my desire is changed into horror.", "webster": "My heart panted, fearfulness affrighted me: the night of my pleasure hath he turned into fear to me.", "vulgate": "emarcuit cor meum tenebrae stupefecerunt me Babylon dilecta mea posita est mihi in miraculum;", "brenton": "My heart wanders, and transgression overwhelms me; my soul is occupied with fear."}}, {"v": 5, "ref": "21:5", "o": "עָרֹ֧ךְ הַ/שֻּׁלְחָ֛ן צָפֹ֥ה הַ/צָּפִ֖ית אָכ֣וֹל שָׁתֹ֑ה ק֥וּמוּ הַ/שָּׂרִ֖ים מִשְׁח֥וּ מָגֵֽן", "en": {"kjv": "Prepare the table, watch in the watchtower, eat, drink: arise, ye princes, and anoint the shield.", "web": "They prepare the table. They set the watch. They eat. They drink. Rise up, you princes, oil the shield!", "bsb": "They prepare a table, they lay out a carpet, they eat, they drink! Rise up, O princes, oil the shields!", "asv": "They prepare the table, they set the watch, they eat, they drink: rise up, ye princes, anoint the shield.", "ylt": "Arrange the table, watch in the watch-tower, Eat, drink, rise, ye heads, anoint the shield,", "dra": "Prepare the table, behold in the watchtower them that eat and drink: arise, ye princes, take up the shield.", "bbe": "They make ready the table, they put down the covers, they take food and drink. Up! you captains; put oil on your breastplates.", "geneva": "Prepare thou the table: watch in the watch towre: eate, drinke: arise, ye princes, anoynt the shielde.", "wycliffe": "Sette thou a boord, biholde thou in to a toting place; rise, ye princes, etynge and drynkynge, take ye scheeld.", "rotherham": "[Ye thought] to prepare the table—spread the mat—eat—drink! …Arise ye chieftains anoint the shield!", "darby": "Prepare the table, appoint the watch; eat, drink: arise, ye princes, anoint the shield.", "twenty": "", "jps": "They prepare the table, they light the lamps, they eat, they drink--' Rise up, ye princes, anoint the shield.'", "acv": "They prepare the table, they set the watch, they eat, they drink. Rise up, ye rulers, anoint the shield.", "anderson": "", "haweis": "", "noyes": "The table is prepared; the watch is set; They eat; they drink; \"Arise, ye princes! Anoint the shield!\"", "webster": "Prepare the table, watch in the watch-tower, eat, drink: arise, ye princes, [and] anoint the shield.", "vulgate": "pone mensam contemplare in specula comedentes bibentes surgite principes arripite clypeum;", "brenton": "Prepare the table, eat, drink: arise, ye princes, and prepare your shields."}}, {"v": 6, "ref": "21:6", "o": "כִּ֣י כֹ֥ה אָמַ֛ר אֵלַ֖/י אֲדֹנָ֑/י לֵ֚ךְ הַעֲמֵ֣ד הַֽ/מְצַפֶּ֔ה אֲשֶׁ֥ר יִרְאֶ֖ה יַגִּֽיד", "en": {"kjv": "For thus hath the Lord said unto me, Go, set a watchman, let him declare what he seeth.", "web": "For the Lord said to me, “Go, set a watchman. Let him declare what he sees.", "bsb": "For this is what the Lord says to me: “Go, post a lookout and have him report what he sees.", "asv": "For thus hath the Lord said unto me, Go, set a watchman; let him declare what he seeth:", "ylt": "For thus said the Lord unto me: `Go, station the watchman, That which he seeth let him declare.'", "dra": "For thus hath the Lord said to me: Go, and set a watchman: and whatsoever he shall see, let him tell.", "bbe": "For so has the Lord said to me, Go, let a watchman be placed; let him give word of what he sees:", "geneva": "For thus hath the Lord said vnto me, Go, set a watchman, to tell what he seeth.", "wycliffe": "For whi the Lord seide these thingis to me, Go thou, and sette a lokere; and telle he, what euer thing he seeth.", "rotherham": "For, thus, hath My Lord said unto me,—Go, set the watchman, What he seeth, let him tell!", "darby": "For thus hath the Lord said unto me: Go, set a watchman, let him declare what he seeth.", "twenty": "", "jps": "For thus hath the L-rd said unto me: Go, set a watchman; let him declare what he seeth!", "acv": "For thus has the Lord said to me, Go, set a watchman. Let him declare what he sees.", "anderson": "", "haweis": "", "noyes": "For thus said the Lord unto me: \"Go, set a watchman, Who shall declare what he seeth.\"", "webster": "For thus hath the Lord said to me, Go, set a watchman, let him declare what he seeth.", "vulgate": "haec enim dixit mihi Dominus vade et pone speculatorem et quodcumque viderit adnuntiet;", "brenton": "For thus said the Lord to me, Go and station a watchman for thyself, and declare whatever thou shalt see."}}, {"v": 7, "ref": "21:7", "o": "וְ/רָ֣אָה רֶ֗כֶב צֶ֚מֶד פָּֽרָשִׁ֔ים רֶ֥כֶב חֲמ֖וֹר רֶ֣כֶב גָּמָ֑ל וְ/הִקְשִׁ֥יב קֶ֖שֶׁב רַב קָֽשֶׁב", "en": {"kjv": "And he saw a chariot with a couple of horsemen, a chariot of asses, and a chariot of camels; and he hearkened diligently with much heed:", "web": "When he sees a troop, horsemen in pairs, a troop of donkeys, a troop of camels, he shall listen diligently with great attentiveness.”", "bsb": "When he sees chariots with teams of horsemen, riders on donkeys, riders on camels, he must be alert, fully alert.”", "asv": "and when he seeth a troop, horsemen in pairs, a troop of asses, a troop of camels, he shall hearken diligently with much heed.", "ylt": "And he hath seen a chariot--a couple of horsemen, The rider of an ass, the rider of a camel, And he hath given attention--He hath increased attention!", "dra": "And he saw a chariot with two horsemen, a rider upon an ass, and a rider upon a camel: and he beheld them diligently with much heed.", "bbe": "And when he sees war-carriages, horsemen by twos, war-carriages with asses, war-carriages with camels, let him give special attention.", "geneva": "And he sawe a charet with two horsemen: a charet of an asse, and a charet of a camel: and he hearkened and tooke diligent heede.", "wycliffe": "And he siy the chare of tweyne horse men, the stiere of an asse, and the stiere of a camel; and he bihelde diligentli with myche lokyng,", "rotherham": "When he seeth A train of horsemen in double rank, A train of asses, A train of camels, Then shall he hearken attentively with diligent heed.", "darby": "And he saw chariots, horsemen by pairs, a chariot with asses, a chariot with camels; and he hearkened diligently with much heed.", "twenty": "", "jps": "And when he seeth a troop, horsemen by pairs, a troop of asses, a troop of camels, he shall hearken diligently with much heed.", "acv": "and when he sees a troop, horsemen in pairs, a troop of donkeys, a troop of camels, he shall hearken diligently with much heed.", "anderson": "", "haweis": "", "noyes": "And he saw a troop, horsemen in pairs, Riders on asses, and riders on camels, And he watched with the utmost heed.", "webster": "And he saw a chariot [with] a couple of horsemen, a chariot of asses, [and] a chariot of camels; and he hearkened diligently with much heed:", "vulgate": "et vidit currum duorum equitum ascensorem asini et ascensorem cameli et contemplatus est diligenter multo intuitu;", "brenton": "And I saw two mounted horsemen, and a rider on an ass, and a rider on a camel."}}, {"v": 8, "ref": "21:8", "o": "וַ/יִּקְרָ֖א אַרְיֵ֑ה עַל מִצְפֶּ֣ה אֲדֹנָ֗/י אָנֹכִ֞י עֹמֵ֤ד תָּמִיד֙ יוֹמָ֔ם וְ/עַל מִ֨שְׁמַרְתִּ֔/י אָנֹכִ֥י נִצָּ֖ב כָּל הַ/לֵּילֽוֹת", "en": {"kjv": "And he cried, A lion: My lord, I stand continually upon the watchtower in the daytime, and I am set in my ward whole nights:", "web": "He cried like a lion: “Lord, I stand continually on the watchtower in the daytime, and every night I stay at my post.", "bsb": "Then the lookout shouted: “Day after day, my lord, I stand on the watchtower; night after night I stay at my post.", "asv": "And he cried as a lion: O Lord, I stand continually upon the watch-tower in the day-time, and am set in my ward whole nights;", "ylt": "And he crieth--a lion, `On a watch-tower my lord, I am standing continually by day, And on my ward I am stationed whole nights.", "dra": "And a lion cried out: I am upon the watchtower of the Lord, standing continually by day: and I am upon my ward, standing whole nights.", "bbe": "And the watchman gave a loud cry, O my lord, I am on the watchtower all day, and am placed in my watch every night:", "geneva": "And he cryed, A lyon: my lorde, I stand continually vpon ye watche towre in the day time, and I am set in my watche euery night:", "wycliffe": "and criede as a lioun, Y stonde contynueli bi dai on the totyng place of the Lord, and Y stonde bi alle nyytis on my kepyng.", "rotherham": "Then cried he. A lion! On the watch, O My Lord, had I been standing continually, by day, And at my post, had I been stationed whole nights;—", "darby": "And he cried [as] a lion, Lord, I stand continually upon the watchtower in the daytime, and I am set in my ward whole nights.", "twenty": "", "jps": "And he cried as a lion: 'Upon the watch-tower, O L-rd, I stand continually in the daytime, and I am set in my ward all the nights.'", "acv": "And he cried out as a lion, O Lord, I stand continually upon the watchtower in the daytime, and am set in my ward whole nights,", "anderson": "", "haweis": "", "noyes": "Then he cried like a lion: \"My Lord, I stand continually upon the watch-tower in the daytime, And keep my post all the night;", "webster": "And he cried, a lion: My lord, I stand continually upon the watch-tower in the day time, and I am set in my ward whole nights.", "vulgate": "et clamavit leo super specula Domini ego sum stans iugiter per diem et super custodiam meam ego sum stans totis noctibus;", "brenton": "Hearken with great attention, and call thou Urias to the watch-tower: the Lord has spoken. I stood continually during the day, and I stood in the camp all night:"}}, {"v": 9, "ref": "21:9", "o": "וְ/הִנֵּה זֶ֥ה בָא֙ רֶ֣כֶב אִ֔ישׁ צֶ֖מֶד פָּֽרָשִׁ֑ים וַ/יַּ֣עַן וַ/יֹּ֗אמֶר נָפְלָ֤ה נָֽפְלָה֙ בָּבֶ֔ל וְ/כָל פְּסִילֵ֥י אֱלֹהֶ֖י/הָ שִׁבַּ֥ר לָ/אָֽרֶץ", "en": {"kjv": "And, behold, here cometh a chariot of men, with a couple of horsemen. And he answered and said, Babylon is fallen, is fallen; and all the graven images of her gods he hath broken unto the ground.", "web": "Behold, here comes a troop of men, horsemen in pairs.” He answered, “Fallen, fallen is Babylon; and all the engraved images of her gods are broken to the ground.", "bsb": "Look, here come the riders, horsemen in pairs.” And one answered, saying: “Fallen, fallen is Babylon! All the images of her gods lie shattered on the ground!”", "asv": "and, behold, here cometh a troop of men, horsemen in pairs. And he answered and said, Fallen, fallen is Babylon; and all the graven images of her gods are broken unto the ground.", "ylt": "And lo, this, the chariot of a man is coming, A couple of horsemen.' And he answereth and saith: `Fallen, fallen hath Babylon, And all the graven images of her gods He hath broken to the earth.", "dra": "Behold this man cometh, the rider upon the chariot with two horsemen, and he answered, and said: Babylon is fallen, she is fallen, and all the graven gods thereof are broken unto the ground.", "bbe": "See, here come war-carriages with men, horsemen by twos: and in answer he said, Babylon is made low, is made low, and all her images are broken on the earth.", "geneva": "And beholde, this mans charet commeth with two horsemen. And he answered and said, Babel is fallen: it is fallen, and all the images of her gods hath he broken vnto the ground.", "wycliffe": "Lo! this cometh, a man stiere of a carte of horse men. And Isaie criede, and seide, Babiloyne felle doun, felle doun; and alle the grauun ymagis of goddis therof ben al to-brokun in to erthe.", "rotherham": "When lo! here was a train of men coming. With horsemen in double rank,—And one began and said, Fallen! fallen! is Babylon, And all the images of her gods, are smashed to the ground!", "darby": "— And behold, there cometh a chariot of men; horsemen by pairs. And he answered and said, Babylon is fallen, is fallen; and all the graven images of hergods he hath broken unto the ground.", "twenty": "", "jps": "And, behold, there came a troop of men, horsemen by pairs. And he spoke and said: 'Fallen, fallen is Babylon; and all the graven images of her gods are broken unto the ground.'", "acv": "and, behold, here comes a troop of men, horsemen in pairs. And he answered and said, Fallen, fallen is Babylon. And all the graven images of her gods are broken to the ground.", "anderson": "", "haweis": "", "noyes": "And behold, there cometh a troop, Horsemen in pairs.\" Again also he lifted up his voice, and said: \"Fallen, fallen is Babylon, And all the graven images of her gods are cast broken to the ground.\"", "webster": "And behold, here cometh a chariot of men, [with] a couple of horsemen. And he answered and said, Babylon is fallen, is fallen; and all the graven images of her gods he hath broken to the ground.", "vulgate": "ecce iste venit ascensor vir bigae equitum et respondit et dixit cecidit cecidit Babylon et omnia sculptilia deorum eius contrita sunt in terram;", "brenton": "and, behold, he comes riding in a chariot and pair: and he answered and said, Babylon is fallen, is fallen; and all her images and her idols have been crushed to the ground."}}, {"v": 10, "ref": "21:10", "o": "מְדֻשָׁתִ֖/י וּ/בֶן גָּרְנִ֑/י אֲשֶׁ֣ר שָׁמַ֗עְתִּי מֵ/אֵ֨ת יְהוָ֧ה צְבָא֛וֹת אֱלֹהֵ֥י יִשְׂרָאֵ֖ל הִגַּ֥דְתִּי לָ/כֶֽם", "en": {"kjv": "O my threshing, and the corn of my floor: that which I have heard of the Lord of hosts, the God of Israel, have I declared unto you.", "web": "You are my threshing, and the grain of my floor!” That which I have heard from Yahweh of Armies, the God of Israel, I have declared to you.", "bsb": "O my people, crushed on the threshing floor, I tell you what I have heard from the LORD of Hosts, the God of Israel.", "asv": "O thou my threshing, and the grain of my floor! that which I have heard from Jehovah of hosts, the God of Israel, have I declared unto you.", "ylt": "O my threshing, and the son of my floor, That which I heard from Jehovah of Hosts, God of Israel, I have declared to you!'", "dra": "O my thrashing, and the children of my floor, that which I have heard of the Lord of hosts, the God of Israel, I have declared unto you.", "bbe": "O my crushed ones, the grain of my floor! I have given you the word which came to me from the Lord of armies, the God of Israel.", "geneva": "O my threshing, and the corne of my floore. That which I haue heard of the Lord of hostes, the God of Israel, haue I shewed vnto you.", "wycliffe": "Mi threschyng, and the douyter of my cornfloor, Y haue teld to you what thingis Y herde of the Lord of oostis, of God of Israel.", "rotherham": "O thou My threshing! And the grain of my corn-floor! That which I have heard from Yahweh of hosts, the God of Israel, Have I declared, unto you.", "darby": "O my threshing, and the corn of my floor! What I have heard of Jehovah of hosts, theGod of Israel, have I declared unto you.", "twenty": "", "jps": "O thou my threshing, and the winnowing of my floor, that which I have heard from HaShem of hosts, the G-d of Israel, have I declared unto you.", "acv": "O my threshing, and the grain of my floor! That which I have heard from Jehovah of hosts, the God of Israel, I have declared to you.", "anderson": "", "haweis": "", "noyes": "O my threshing, and the corn of my floor! What I have heard from Jehovah of hosts, the God of Israel, That have I declared to you.", "webster": "O my threshing, and the corn of my floor; that which I have heard from the LORD of hosts, the God of Israel, have I declared to you.", "vulgate": "tritura mea et fili areae meae quae audivi a Domino exercituum Deo Israhel adnuntiavi vobis;", "brenton": "Hear, ye that are left, and ye that are in pain, hear what things I have heard of the Lord of hosts which the God of Israel has declared to us. THE VISION OF IDUMEA."}}, {"v": 11, "ref": "21:11", "o": "מַשָּׂ֖א דּוּמָ֑ה אֵלַ/י֙ קֹרֵ֣א מִ/שֵּׂעִ֔יר שֹׁמֵר֙ מַה מִ/לַּ֔יְלָה שֹׁמֵ֖ר מַה מִ/לֵּֽיל", "en": {"kjv": "The burden of Dumah. He calleth to me out of Seir, Watchman, what of the night? Watchman, what of the night?", "web": "The burden of Dumah. One calls to me out of Seir, “Watchman, what of the night? Watchman, what of the night?”", "bsb": "This is the burden against Dumah: One calls to me from Seir, “Watchman, what is left of the night? Watchman, what is left of the night?”", "asv": "The burden of Dumah. One calleth unto me out of Seir, Watchman, what of the night? Watchman, what of the night?", "ylt": "The burden of Dumah. Unto me is one calling from Seir `Watchman, what of the night? Watchman, what of the night?'", "dra": "The burden of Duma calleth to me out of Seir: Watchman, what of the night? watchman, what of the night?", "bbe": "The word about Edom. A voice comes to me from Seir, Watchman, how far gone is the night? how far gone is the night?", "geneva": "The burden of Dumah. He calleth vnto me out of Seir, Watchman, what was in ye night? Watchman, what was in the night?", "wycliffe": "The birthun of Duma. It crieth fro Seir to me, Kepere, what our of the niyt? `kepere, what our of the niyt?", "rotherham": "The oracle on Dumah: Unto me, is one crying—out of Seir, Watchman! how far gone is the night? Watchman, how far gone is the night?", "darby": "The burden of Dumah. He calleth to me out of Seir, Watchman, what of the night? Watchman, what of the night?", "twenty": "", "jps": "The burden of Dumah. One calleth unto me out of Seir: 'Watchman, what of the night? Watchman, what of the night?'", "acv": "The burden of Dumah. He calls to me out of Seir, Watchman, what of the night? Watchman, what of the night?", "anderson": "", "haweis": "", "noyes": "The prophecy concerning Dumah. A voice came to me from Seir: \"Watchman, what of the night? Watchman, what of the night?\"", "webster": "The burden of Dumah. He calleth to me out of Seir, Watchman, what of the night? Watchman, what of the night?", "vulgate": "onus Duma ad me clamat ex Seir custos quid de nocte custos quid de nocte;", "brenton": "Call to me out of Seir; guard ye the bulwarks."}}, {"v": 12, "ref": "21:12", "o": "אָמַ֣ר שֹׁמֵ֔ר אָתָ֥ה בֹ֖קֶר וְ/גַם לָ֑יְלָה אִם תִּבְעָי֥וּ/ן בְּעָ֖יוּ שֻׁ֥בוּ אֵתָֽיוּ", "en": {"kjv": "The watchman said, The morning cometh, and also the night: if ye will enquire, enquire ye: return, come.", "web": "The watchman said, “The morning comes, and also the night. If you will inquire, inquire. Come back again.”", "bsb": "The watchman replies, “Morning has come, but also the night. If you would inquire, then inquire. Come back yet again.”", "asv": "The watchman said, The morning cometh, and also the night: if ye will inquire, inquire ye: turn ye, come.", "ylt": "The watchman hath said, `Come hath morning, and also night, If ye inquire, inquire ye, turn back, come.'", "dra": "The watchman said: The morning cometh, also the night: if you seek, seek: return, come.", "bbe": "The watchman says, The morning has come, but night is still to come: if you have questions to put, put them, and come back again.", "geneva": "The watchman saide, The morning commeth, and also the night. If yee will aske, enquire: returne and come.", "wycliffe": "The kepere seide, Morewtid cometh, and niyt; if ye seken, seke ye, and be ye conuertid, and `come ye.", "rotherham": "Said the watchman, There cometh a morning. But also a night,—If ye will enquire, enquire, ye—Come, again!", "darby": "The watchman said, The morning cometh, and also the night: if ye will inquire, inquire; return, come.", "twenty": "", "jps": "The watchman said: 'The morning cometh, and also the night--if ye will inquire, inquire ye; return, come.'", "acv": "The watchman said, The morning comes, and also the night. If ye will inquire, inquire ye; turn ye back, come.", "anderson": "", "haweis": "", "noyes": "The watchman saith: \"Morning cometh, and also night. If ye will inquire, inquire! Return, come!\"", "webster": "The watchman said, The morning cometh, and also the night: if ye will inquire, inquire ye: return, come.", "vulgate": "dixit custos venit mane et nox si quaeritis quaerite convertimini venite;", "brenton": "I watch in the morning and the night: if thou wouldest enquire, enquire, and dwell by me."}}, {"v": 13, "ref": "21:13", "o": "מַשָּׂ֖א בַּ/עְרָ֑ב בַּ/יַּ֤עַר בַּ/עְרַב֙ תָּלִ֔ינוּ אֹֽרְח֖וֹת דְּדָנִֽים", "en": {"kjv": "The burden upon Arabia. In the forest in Arabia shall ye lodge, O ye travelling companies of Dedanim.", "web": "The burden on Arabia. In the forest in Arabia you will lodge, you caravans of Dedanites.", "bsb": "This is the burden against Arabia: In the thickets of Arabia you must lodge, O caravans of Dedanites.", "asv": "The burden upon Arabia. In the forest in Arabia shall ye lodge, O ye caravans of Dedanites.", "ylt": "The burden on Arabia. In a forest in Arabia ye lodge, O travellers of Dedanim.", "dra": "The burden in Arabia. In the forest at evening you shall sleep, in the paths of Dedanim.", "bbe": "The word about Arabia. In the thick woods of Arabia will be your night's resting-place, O travelling bands of Dedanites!", "geneva": "The burden against Arabia. In the forest of Arabia shall yee tarie all night, euen in the waies of Dedanim.", "wycliffe": "The birthun in Arabie. In the forest at euentid ye schulen slepe, in the pathis of Dodanym.", "rotherham": "The oracle on Arabia,—Among the shrubs in Arabia, must ye lodge, Ye caravans of Dedanites.", "darby": "The burden against Arabia. In the forest of Arabia shall ye lodge, [ye] caravans of Dedanites.", "twenty": "", "jps": "The burden upon Arabia. In the thickets in Arabia shall ye lodge, O ye caravans of Dedanites.", "acv": "The burden upon Arabia. In the forest in Arabia ye shall lodge, O ye caravans of Dedanites.", "anderson": "", "haweis": "", "noyes": "The prophecy against the Arabians. In the thickets of Arabia shall ye lodge, O ye caravans of Dedan!", "webster": "The burden upon Arabia. In the forest in Arabia shall ye lodge, O ye traveling companies of Dedanim.", "vulgate": "onus in Arabia in saltu ad vesperam dormietis in semitis Dodanim;", "brenton": "Thou mayest lodge in the forest in the evening, or in the way of Daedan."}}, {"v": 14, "ref": "21:14", "o": "לִ/קְרַ֥את צָמֵ֖א הֵתָ֣יוּ מָ֑יִם יֹשְׁבֵי֙ אֶ֣רֶץ תֵּימָ֔א בְּ/לַחְמ֖/וֹ קִדְּמ֥וּ נֹדֵֽד", "en": {"kjv": "The inhabitants of the land of Tema brought water to him that was thirsty, they prevented with their bread him that fled.", "web": "They brought water to him who was thirsty. The inhabitants of the land of Tema met the fugitives with their bread.", "bsb": "Bring water for the thirsty, O dwellers of Tema; meet the refugees with food.", "asv": "Unto him that was thirsty they brought water; the inhabitants of the land of Tema did meet the fugitives with their bread.", "ylt": "To meet the thirsty brought water have Inhabitants of the land of Tema, With his bread they came before a fugitive.", "dra": "Meeting the thirsty bring him water, you that inhabit the land of the south, meet with bread him that fleeth.", "bbe": "Give water to him who is in need of water; give bread, O men of the land of Tema, to those in flight.", "geneva": "O inhabitants of the lande of Tema, bring foorth water to meete the thirstie, and preuent him that fleeth with his bread.", "wycliffe": "Ye that dwellen in the lond of the south, renne, and bere watir to the thristi; and renne ye with looues to hym that fleeth.", "rotherham": "To meet the thirsty, bring ye water,—Ye dwellers in the land of Tema; With bread for him, get in advance of him that is in flight!", "darby": "Bring ye water to meet the thirsty! The inhabitants of the land of Tema come forth with their bread for him that fleeth.", "twenty": "", "jps": "Unto him that is thirsty bring ye water! The inhabitants of the land of Tema did meet the fugitive with his bread.", "acv": "To him who was thirsty they brought water. The inhabitants of the land of Tema met the fugitives with their bread.", "anderson": "", "haweis": "", "noyes": "The inhabitants of the land of Tema Bring water to the thirsty; They come to meet the fugitive with bread.", "webster": "The inhabitants of the land of Tema brought water to him that was thirsty, they met with their bread him that fled.", "vulgate": "occurrentes sitienti ferte aquam qui habitatis terram austri cum panibus occurrite fugienti;", "brenton": "Ye that dwell in the country of Thaeman, bring water to meet him that is thirsty;"}}, {"v": 15, "ref": "21:15", "o": "כִּֽי מִ/פְּנֵ֥י חֲרָב֖וֹת נָדָ֑דוּ מִ/פְּנֵ֣י חֶ֣רֶב נְטוּשָׁ֗ה וּ/מִ/פְּנֵי֙ קֶ֣שֶׁת דְּרוּכָ֔ה וּ/מִ/פְּנֵ֖י כֹּ֥בֶד מִלְחָמָֽה", "en": {"kjv": "For they fled from the swords, from the drawn sword, and from the bent bow, and from the grievousness of war.", "web": "For they fled away from the swords, from the drawn sword, from the bent bow, and from the heat of battle.", "bsb": "For they flee from the sword— the sword that is drawn— from the bow that is bent, and from the stress of battle.", "asv": "For they fled away from the swords, from the drawn sword, and from the bent bow, and from the grievousness of war.", "ylt": "For from the face of destructions they fled, From the face of a stretched-out sword, And from the face of a trodden bow, And from the face of the grievousness of battle.", "dra": "For they are fled from before the swords, from the sword that hung over them, from the bent bow, from the face of a grievous battle.", "bbe": "For they are in flight from the sharp sword, and the bent bow, and from the trouble of war.", "geneva": "For they flee from the drawen swords, euen from the drawen sword, and from the bent bowe, and from the grieuousnesse of warre.", "wycliffe": "For thei fledden fro the face of swerdis, fro the face of swerd neiyynge, fro the face of bouwe bent, fro the face of greuouse batel.", "rotherham": "For, before swords, have they fled: Before a sword that is drawn, Before a bow that is bent, And before the stress of war.", "darby": "For they flee from the swords, from the drawn sword, and from the bent bow, and from the grievousness of war.", "twenty": "", "jps": "For they fled away from the swords, from the drawn sword, and from the bent bow, and from the grievousness of war.", "acv": "For they fled away from the swords, from the drawn sword, and from the bent bow, and from the grievousness of war.", "anderson": "", "haweis": "", "noyes": "For they flee from swords, From the drawn sword, And from the bent bow, And from the fury of war.", "webster": "For they fled from the swords, from the drawn sword, and from the bent bow, and from the grievousness of war.", "vulgate": "a facie enim gladiorum fugerunt a facie gladii inminentis a facie arcus extenti a facie gravis proelii;", "brenton": "meet the fugitives with bread, because of the multitude of the slain, and because of the multitude of them that lose their way, and because of the multitude of swords, and because of the multitude of bent bows, and because of the multitude of them that have fallen in war."}}, {"v": 16, "ref": "21:16", "o": "כִּי כֹ֛ה אָמַ֥ר אֲדֹנָ֖/י אֵלָ֑/י בְּ/ע֤וֹד שָׁנָה֙ כִּ/שְׁנֵ֣י שָׂכִ֔יר וְ/כָלָ֖ה כָּל כְּב֥וֹד קֵדָֽר", "en": {"kjv": "For thus hath the Lord said unto me, Within a year, according to the years of an hireling, and all the glory of Kedar shall fail:", "web": "For the Lord said to me, “Within a year, as a worker bound by contract would count it, all the glory of Kedar will fail,", "bsb": "For this is what the Lord says to me: “Within one year, as a hired worker would count it, all the glory of Kedar will be gone.", "asv": "For thus hath the Lord said unto me, Within a year, according to the years of a hireling, all the glory of Kedar shall fail;", "ylt": "For thus said the Lord unto me: `Within a year, as years of a hireling, Consumed hath been all the honour of Kedar.", "dra": "For thus saith the Lord to me: Within a year, according to the years of a hireling, all the glory of Cedar shall be taken away.", "bbe": "For so has the Lord said to me, In a year, by the years of a servant working for payment, all the glory of Kedar will come to an end:", "geneva": "For thus hath the Lord sayd vnto me, Yet a yeere according to the yeeres of an hireling, and all the glorie of Kedar shall faile.", "wycliffe": "For the Lord seith these thingis to me, Yit in o yeer, as in the yeer of an hirid man, and al the glorie of Cedar schal be takun awei.", "rotherham": "For, thus, hath My Lord said unto me,—Within a year according to the yearn of a hireling, shall fail all the glory of Kedar;", "darby": "For thus hath the Lord said unto me: Within a year, according to the years of a hired servant, and all the glory of Kedar shall fail;", "twenty": "", "jps": "For thus hath the L-rd said unto me: 'Within a year, according to the years of a hireling, and all the glory of Kedar shall fail;", "acv": "For thus the Lord has said to me, Within a year, according to the years of a hireling, all the glory of Kedar shall fail.", "anderson": "", "haweis": "", "noyes": "For thus saith the Lord to me: Within one year, according to the years of a hireling, Shall all the glory of Kedar be consumed.", "webster": "For thus hath the Lord said to me, Within a year, according to the years of a hireling, and all the glory of Kedar shall fail:", "vulgate": "quoniam haec dicit Dominus ad me adhuc in uno anno quasi in anno mercennarii et auferetur omnis gloria Cedar;", "brenton": "For thus said the Lord to me, Yet a year, as the year of an hireling, and the glory of the sons of Kedar shall fail:"}}, {"v": 17, "ref": "21:17", "o": "וּ/שְׁאָ֧ר מִסְפַּר קֶ֛שֶׁת גִּבּוֹרֵ֥י בְנֵֽי קֵדָ֖ר יִמְעָ֑טוּ כִּ֛י יְהוָ֥ה אֱלֹהֵֽי יִשְׂרָאֵ֖ל דִּבֵּֽר", "en": {"kjv": "And the residue of the number of archers, the mighty men of the children of Kedar, shall be diminished: for the Lord God of Israel hath spoken it.", "web": "and the residue of the number of the archers, the mighty men of the children of Kedar, will be few; for Yahweh, the God of Israel, has spoken it.”", "bsb": "The remaining archers, the warriors of Kedar, will be few.” For the LORD, the God of Israel, has spoken.", "asv": "and the residue of the number of the archers, the mighty men of the children of Kedar, shall be few; for Jehovah, the God of Israel, hath spoken it.", "ylt": "And the remnant of the number of bow-men, The mighty of the sons of Kedar are few, For Jehovah, God of Israel, hath spoken!'", "dra": "And the residue of the number of strong archers of the children of Cedar shall be diminished: for the Lord the God of Israel hath spoken it.", "bbe": "And the rest of the bowmen, the men of war of the children of Kedar, will be small in number: for the Lord, the God of Israel, has said it.", "geneva": "And the residue of the nomber of ye strong archers of the sonnes of Kedar shall be fewe: for the Lord God of Israel hath spoken it.", "wycliffe": "And the remenauntis of the noumbre of stronge archeris of the sones of Cedar schulen be maad lesse; for whi the Lord God of Israel spak.", "rotherham": "And, the remnant of the record of bowmen, The heroes of the sons of Kedar, shall become few; For Yahweh God of Israel, hath spoken.", "darby": "and the residue of the number of the archers, the mighty men of the sons of Kedar, shall be diminished: for Jehovah, theGod of Israel, hath spoken.", "twenty": "", "jps": "and the residue of the number of the archers, the mighty men of the children of Kedar, shall be diminished; for HaShem, the G-d of Israel, hath spoken it.'", "acv": "And the residue of the number of the archers, the mighty men of the sons of Kedar, shall be few. For Jehovah, the God of Israel, has spoken it.", "anderson": "", "haweis": "", "noyes": "The remainder of the mighty bowmen of the sons of Kedar shall be diminished; For Jehovah, the God of Israel, hath said it.", "webster": "And the residue of the number of archers, the mighty men of the children of Kedar, shall be diminished: for the LORD God of Israel hath spoken [it].", "vulgate": "et reliquiae numeri sagittariorum fortium de filiis Cedar inminuentur Dominus enim Deus Israhel locutus est;", "brenton": "and the remnant of the strong bows of the sons of Kedar shall be small: for the Lord God of Israel has spoken it."}}]}, {"c": 22, "verses": [{"v": 1, "ref": "22:1", "o": "מַשָּׂ֖א גֵּ֣יא חִזָּי֑וֹן מַה לָּ֣/ךְ אֵפ֔וֹא כִּֽי עָלִ֥ית כֻּלָּ֖/ךְ לַ/גַּגּֽוֹת", "en": {"kjv": "The burden of the valley of vision. What aileth thee now, that thou art wholly gone up to the housetops?", "web": "The burden of the valley of vision. What ails you now, that you have all gone up to the housetops?", "bsb": "This is the burden against the Valley of Vision: What ails you now, that you have all gone up to the rooftops,", "asv": "The burden of the valley of vision. What aileth thee now, that thou art wholly gone up to the housetops?", "ylt": "The burden of the Valley of Vision. What--to thee, now, that thou hast gone up, All of thee--to the roofs?", "dra": "The burden of the valley of vision. What aileth thee also, that thou too art wholly gone up to the housetops?", "bbe": "The word about the valley of vision. Why have all your people gone up to the house-tops?", "geneva": "The burden of the valley of vision. What aileth thee nowe that thou art wholy gone vp vnto the house toppes?", "wycliffe": "The birthun of the valei of visioun. What also is to thee, for and al thou stiedist in to roouys,", "rotherham": "The oracle on the valley of vision,—What aileth thee, then, That thou art wholly gone up to the house-tops?", "darby": "The burden of the valley of vision. What aileth thee now, that thou art wholly gone up to the housetops?", "twenty": "", "jps": "The burden concerning the Valley of Vision. What aileth thee now, that thou art wholly gone up to the housetops,", "acv": "The burden of the valley of vision. What troubles thee now, that thou have wholly gone up to the housetops?", "anderson": "", "haweis": "", "noyes": "The prophecy concerning the valley of vision. What aileth thee now, That all thine inhabitants are gone up to the house-tops?", "webster": "The burden of the valley of vision. What aileth thee now, that thou hast wholly gone up to the house-tops?", "vulgate": "onus vallis Visionis quidnam tibi quoque est quia ascendisti et tu omnis in tecta;", "brenton": "THE WORD OF THE VALLEY OF SION. What has happened to thee, that now ye are all gone up to the housetops which help you not?"}}, {"v": 2, "ref": "22:2", "o": "תְּשֻׁא֣וֹת מְלֵאָ֗ה עִ֚יר הֽוֹמִיָּ֔ה קִרְיָ֖ה עַלִּיזָ֑ה חֲלָלַ֨יִ/ךְ֙ לֹ֣א חַלְלֵי חֶ֔רֶב וְ/לֹ֖א מֵתֵ֥י מִלְחָמָֽה", "en": {"kjv": "Thou that art full of stirs, a tumultuous city, a joyous city: thy slain men are not slain with the sword, nor dead in battle.", "web": "You that are full of shouting, a tumultuous city, a joyous town; your slain are not slain with the sword, neither are they dead in battle.", "bsb": "O city of commotion, O town of revelry? Your slain did not die by the sword, nor were they killed in battle.", "asv": "O thou that art full of shoutings, a tumultuous city, a joyous town; thy slain are not slain with the sword, neither are they dead in battle.", "ylt": "Full of stirs--a noisy city--an exulting city, Thy pierced are not pierced of the sword, Nor dead in battle.", "dra": "Full of clamour, a populous city, a joyous city: thy slain are not slain by the sword, nor dead in battle.", "bbe": "You, who are full of loud voices, a town of outcries, given up to joy; your dead men have not been put to the sword, or come to their death in war.", "geneva": "Thou that art full of noise, a citie full of brute, a ioyous citie: thy slaine men shall not bee slaine with sworde, nor die in battell.", "wycliffe": "thou ful of cry, a citee of myche puple, a citee ful out ioiynge? thi slayn men weren not slayn bi swerd, nether thi deed men weren deed in batel.", "rotherham": "With tumults, art thou filled, thou citadel in commotion! city exultant! Thy slain, are Not the slain, of the sword, Nor the dead in battle.", "darby": "Thou that wast full of stir, a town of tumult, a joyous city: thy slain men are not slain with the sword, nor dead in battle.", "twenty": "", "jps": "Thou that art full of uproar, a tumultuous city, a joyous town? Thy slain are not slain with the sword, nor dead in battle.", "acv": "O thou that are full of shoutings, a tumultuous city, a joyous town. Thy slain are not slain with the sword, nor are they dead in battle.", "anderson": "", "haweis": "", "noyes": "Thou that wast full of noise, A tumultuous city, a joyous city! Thy slain fall not by the sword; They are not slain in battle.", "webster": "Thou that art full of stirs, a tumultuous city, a joyous city: thy slain [men are] not slain with the sword, nor dead in battle.", "vulgate": "clamoris plena urbs frequens civitas exultans interfecti tui non interfecti gladio nec mortui in bello;", "brenton": "The city is filled with shouting men: thy slain are not slain with swords, nor are thy dead those who have died in battle."}}, {"v": 3, "ref": "22:3", "o": "כָּל קְצִינַ֥יִ/ךְ נָֽדְדוּ יַ֖חַד מִ/קֶּ֣שֶׁת אֻסָּ֑רוּ כָּל נִמְצָאַ֨יִ/ךְ֙ אֻסְּר֣וּ יַחְדָּ֔ו מֵ/רָח֖וֹק בָּרָֽחוּ", "en": {"kjv": "All thy rulers are fled together, they are bound by the archers: all that are found in thee are bound together, which have fled from far.", "web": "All your rulers fled away together. They were bound by the archers. All who were found by you were bound together. They fled far away.", "bsb": "All your rulers have fled together, captured without a bow. All your fugitives were captured together, having fled to a distant place.", "asv": "All thy rulers fled away together, they were bound by the archers; all that were found of thee were bound together; they fled afar off.", "ylt": "All thy rulers fled together from the bow, Bound have been all found of thee, They have been kept bound together, Afar off they have fled.", "dra": "All the princes are fled together, and are bound hard: all that were found, are bound together, they are fled far off.", "bbe": "All your rulers ... have gone in flight; all your strong ones have gone far away.", "geneva": "All thy princes shall flee together from the bowe: they shalbe bound: all that shall be found in thee, shall be bound together, which haue fled from farre.", "wycliffe": "Alle thi princes fledden togidere, and weren boundun harde; alle that weren foundun, weren boundun togidere, thei fledden fer.", "rotherham": "All thy ruler, having fled, together, by the bow, are taken captive: All found in thee have been taken captive, together, Far away, have they fled.", "darby": "All thy rulers have fled together, they are taken prisoners without the bow: all that are found of thee are made prisoners together; they were fleeing far off.", "twenty": "", "jps": "All thy rulers are fled together, without the bow they are bound; all that are found of thee are bound together, they are fled afar off.", "acv": "All thy rulers fled away together. They were bound by the archers. All who were found of thee were bound together; they fled afar off.", "anderson": "", "haweis": "", "noyes": "All thy leaders flee together, By the bowmen are they bound; All found within thee are made captive together, Even they who have fled from afar.", "webster": "All thy rulers have fled together, they are bound by the archers: all that are found in thee are bound together, [who] have fled from far.", "vulgate": "cuncti principes tui fugerunt simul dureque ligati sunt omnes qui inventi sunt vincti sunt pariter procul fugerunt;", "brenton": "All thy princes have fled, and thy captives are tightly bound, and the mighty men in thee have fled far away."}}, {"v": 4, "ref": "22:4", "o": "עַל כֵּ֥ן אָמַ֛רְתִּי שְׁע֥וּ מִ/נִּ֖י אֲמָרֵ֣ר בַּ/בֶּ֑כִי אַל תָּאִ֣יצוּ לְ/נַֽחֲמֵ֔/נִי עַל שֹׁ֖ד בַּת עַמִּֽ/י", "en": {"kjv": "Therefore said I, Look away from me; I will weep bitterly, labour not to comfort me, because of the spoiling of the daughter of my people.", "web": "Therefore I said, “Look away from me. I will weep bitterly. Don’t labor to comfort me for the destruction of the daughter of my people.", "bsb": "Therefore I said, “Turn away from me, let me weep bitterly! Do not try to console me over the destruction of the daughter of my people.”", "asv": "Therefore said I, Look away from me, I will weep bitterly; labor not to comfort me for the destruction of the daughter of my people.", "ylt": "Therefore I said, `Look ye from me, I am bitter in my weeping, Haste not to comfort me, For the destruction of the daughter of my people.'", "dra": "Therefore have I said: Depart from me, I will weep bitterly: labour not to comfort me, for the devastation of the daughter of my people.", "bbe": "For this cause I have said, Let your eyes be turned away from me in my bitter weeping; I will not be comforted for the wasting of the daughter of my people.", "geneva": "Therefore said I, Turne away from me: I wil weepe bitterly: labour not to comfort mee for the destruction of the daughter of my people.", "wycliffe": "Therfor Y seide, Go ye awei fro me, Y schal wepe bittirli; nyle ye be bisie to coumforte me on the distriyng of the douyter of my puple.", "rotherham": "For this cause, I said—Look away from me, Bitterly, will I weep,—Do not press to comfort me, For the ruin of the daughter of my people.", "darby": "Therefore said I, Look away from me; let me weep bitterly: labour not to comfort me, because of the spoiling of the daughter of my people.", "twenty": "", "jps": "Therefore said I: 'Look away from me, I will weep bitterly; strain not to comfort me, for the destruction of the daughter of my people.'", "acv": "Therefore I said, Look away from me. I will weep bitterly. Labor not to comfort me for the destruction of the daughter of my people.", "anderson": "", "haweis": "", "noyes": "Therefore, say I, look away from me, that I may weep bitterly; Strive not to comfort me for the desolation of the daughter of my people!", "webster": "Therefore said I, Look away from me; I will weep bitterly, labor not to comfort me, because of the devastation of the daughter of my people.", "vulgate": "propterea dixi recedite a me amare flebo nolite incumbere ut consolemini me super vastitate filiae populi mei;", "brenton": "Therefore I said, Let me alone, I will weep bitterly; labour not to comfort me for the breach of the daughter of my people."}}, {"v": 5, "ref": "22:5", "o": "כִּ֣י יוֹם֩ מְהוּמָ֨ה וּ/מְבוּסָ֜ה וּ/מְבוּכָ֗ה לַֽ/אדֹנָ֧/י יְהוִ֛ה צְבָא֖וֹת בְּ/גֵ֣יא חִזָּי֑וֹן מְקַרְקַ֥ר קִ֖ר וְ/שׁ֥וֹעַ אֶל הָ/הָֽר", "en": {"kjv": "For it is a day of trouble, and of treading down, and of perplexity by the Lord God of hosts in the valley of vision, breaking down the walls, and of crying to the mountains.", "web": "For it is a day of confusion, and of treading down, and of perplexity, from the Lord, Yahweh of Armies, in the valley of vision; a breaking down of the walls, and a crying to the mountains.”", "bsb": "For the Lord GOD of Hosts has set a day of tumult and trampling and confusion in the Valley of Vision— of breaking down the walls and crying to the mountains.", "asv": "For it is a day of discomfiture, and of treading down, and of perplexity, from the Lord, Jehovah of hosts, in the valley of vision; a breaking down of the walls, and a crying to the mountains.", "ylt": "For a day of noise, and of treading down, And of perplexity, is to the Lord, Jehovah of Hosts, In the valley of vision, digging down a wall, And crying unto the mountain.", "dra": "For it is a day of slaughter and of treading down, and of weeping to the Lord the God of hosts in the valley of vision, searching the wall, and magnificent upon the mountain.", "bbe": "For it is a day of trouble and of crushing down and of destruction from the Lord, the Lord of armies, in the valley of vision; ...", "geneva": "For it is a day of trouble, and of ruine, and of perplexitie by the Lord God of hostes in the valley of vision, breaking downe the citie: and a crying vnto the mountaines.", "wycliffe": "For whi a dai of sleyng, and of defoulyng, and of wepyngis, is ordeined of the Lord God of oostis, in the valei of visioun; and he serchith the walle, and is worschipful on the hil.", "rotherham": "For a day of confusion and downtreading and perplexity, pertaineth to My Lord, Yahweh of hosts, in the valley of vision, an undermining of walls, and a crying for help to the mountain.", "darby": "For it is a day of trouble, and of treading down, and of perplexity, from the Lord, Jehovah of hosts, in the valley of vision; [a day of] breaking down the wall, and of crying to the mountain:", "twenty": "", "jps": "For it is a day of trouble, and of trampling, and of perplexity, from the L-rd, the GOD of hosts, in the Valley of Vision; Kir shouting, and Shoa at the mount.", "acv": "For it is a day of trouble, and of treading down, and of perplexity, from the Lord, Jehovah of hosts, in the valley of vision, a breaking down of the walls, and a crying to the mountains.", "anderson": "", "haweis": "", "noyes": "For a day of trouble, of desolation, and of perplexity cometh From the Lord, Jehovah of hosts, in the valley of vision. They break down the walls; The cry reacheth to the mountains.", "webster": "For [it is] a day of trouble, and of treading down, and of perplexity by the Lord GOD of hosts in the valley of vision, breaking down the walls, and of crying to the mountains.", "vulgate": "dies enim interfectionis et conculcationis et fletuum Domino Deo exercituum in valle Visionis scrutans murum et magnificus super montem;", "brenton": "For it is a day of trouble, and of destruction, and of treading down, and there is perplexity sent from the Lord of hosts: they wander in the valley of Sion; they wander from the least to the greatest on the mountains."}}, {"v": 6, "ref": "22:6", "o": "וְ/עֵילָם֙ נָשָׂ֣א אַשְׁפָּ֔ה בְּ/רֶ֥כֶב אָדָ֖ם פָּֽרָשִׁ֑ים וְ/קִ֥יר עֵרָ֖ה מָגֵֽן", "en": {"kjv": "And Elam bare the quiver with chariots of men and horsemen, and Kir uncovered the shield.", "web": "Elam carried his quiver, with chariots of men and horsemen; and Kir uncovered the shield.", "bsb": "Elam takes up a quiver, with chariots and horsemen, and Kir uncovers the shield.", "asv": "And Elam bare the quiver, with chariots of men and horsemen; and Kir uncovered the shield.", "ylt": "And Elam hath borne a quiver, In a chariot of men--horsemen, And Kir hath exposed a shield.", "dra": "And Elam took the quiver, the chariot of the horseman, and the shield was taken down from the wall.", "bbe": "And Elam was armed with arrows, and Aram came on horseback; and the breastplate of Kir was uncovered.", "geneva": "And Elam bare the quiuer in a mans charet with horsemen, and Kir vncouered the shield.", "wycliffe": "And Helam took an arowe caas, and the chare of an horse man; and the scheeld made nakid the wal.", "rotherham": "Yea, Elam, beareth the quiver, With trains of men, [and] horsemen,—And, Kir, hath uncovered the shield.", "darby": "— Elam beareth the quiver with chariots of men [and] horsemen; and Kir uncovereth the shield.", "twenty": "", "jps": "And Elam bore the quiver, with troops of men, even horsemen; and Kir uncovered the shield.", "acv": "And Elam bore the quiver, with chariots of men and horsemen, and Kir uncovered the shield.", "anderson": "", "haweis": "", "noyes": "Elam beareth the quiver, With chariots full of men, and with horsemen; Kir uncovereth the shield.", "webster": "And Elam bore the quiver with chariots of men [and] horsemen, and Kir uncovered the shield.", "vulgate": "et Aelam sumpsit faretram currum hominis equitis et parietem nudavit clypeus;", "brenton": "And the Elamites took their quivers, and there were men mounted on horses, and there was a gathering for battle."}}, {"v": 7, "ref": "22:7", "o": "וַ/יְהִ֥י מִבְחַר עֲמָקַ֖יִ/ךְ מָ֣לְאוּ רָ֑כֶב וְ/הַ/פָּ֣רָשִׁ֔ים שֹׁ֖ת שָׁ֥תוּ הַ/שָּֽׁעְרָ/ה", "en": {"kjv": "And it shall come to pass, that thy choicest valleys shall be full of chariots, and the horsemen shall set themselves in array at the gate.", "web": "Your choicest valleys were full of chariots, and the horsemen set themselves in array at the gate.", "bsb": "Your choicest valleys are full of chariots, and horsemen are posted at the gates.", "asv": "And it came to pass, that thy choicest valleys were full of chariots, and the horsemen set themselves in array at the gate.", "ylt": "And it cometh to pass, The choice of thy valleys have been full of chariots, And the horsemen place themselves diligently at the gate.", "dra": "And thy choice valleys shall be full of chariots, and the horsemen shall place themselves in the gate.", "bbe": "And your most fertile valleys were full of war-carriages, and the horsemen took up their positions in front of the town.", "geneva": "And thy chiefe valleis were full of charets, and the horsemen set themselues in aray against the gate.", "wycliffe": "And thi chosun valeis, Jerusalem, schulen be ful of cartis; and knyytis schulen putte her seetis in the yate.", "rotherham": "And it hath come to pass that the choice of thy vales, are full of chariots; Yea, the horsemen, have set themselves, in array, at the gate.", "darby": "And it shall come to pass [that] thy choicest valleys shall be full of chariots, and the horsemen shall set themselves in array at the gate.", "twenty": "", "jps": "And it came to pass, when thy choicest valleys were full of chariots, and the horsemen set themselves in array at the gate,", "acv": "And it came to pass, that thy choicest valleys were full of chariots, and the horsemen set themselves in array at the gate.", "anderson": "", "haweis": "", "noyes": "Thy fairest valleys, [O Jerusalem,] are full of chariots; The horsemen set themselves in array against the gate;", "webster": "And it shall come to pass, [that] thy choicest valleys shall be full of chariots, and the horsemen shall set themselves in array at the gate.", "vulgate": "et erunt electae valles tuae plenae quadrigarum et equites ponent sedes suas in porta;", "brenton": "And it shall be that thy choice valleys shall be filled with chariots, and horsemen shall block up thy gates."}}, {"v": 8, "ref": "22:8", "o": "וַ/יְגַ֕ל אֵ֖ת מָסַ֣ךְ יְהוּדָ֑ה וַ/תַּבֵּט֙ בַּ/יּ֣וֹם הַ/ה֔וּא אֶל נֶ֖שֶׁק בֵּ֥ית הַ/יָּֽעַר", "en": {"kjv": "And he discovered the covering of Judah, and thou didst look in that day to the armour of the house of the forest.", "web": "He took away the covering of Judah; and you looked in that day to the armor in the house of the forest.", "bsb": "He has uncovered the defenses of Judah. On that day you looked to the weapons in the House of the Forest.", "asv": "And he took away the covering of Judah; and thou didst look in that day to the armor in the house of the forest.", "ylt": "And one removeth the covering of Judah, And thou lookest in that day Unto the armour of the house of the forest,", "dra": "And the covering of Juda shall be discovered, and thou shalt see in that day the armoury of the house of the forest.", "bbe": "He took away the cover of Judah; and in that day you were looking with care at the store of arms in the house of the woods.", "geneva": "And hee discouered the couering of Iudah: and thou didest looke in that day to the armour of the house of the forest.", "wycliffe": "And the hilyng of Juda schal be schewid; and thou schalt se in that dai the place of armuris of the hous of the forest;", "rotherham": "Then removed he the veil of Judah,—Yea thou didst peer on that day, into the armoury of the forest-house;", "darby": "And he uncovereth the covering of Judah: and thou didst look in that day to the armour in the house of the forest;", "twenty": "", "jps": "And the covering of Judah was laid bare, that thou didst look in that day to the armour in the house of the forest.", "acv": "And he took away the covering of Judah, and thou looked in that day to the armor in the house of the forest.", "anderson": "", "haweis": "", "noyes": "The veil of Judah is torn from her. But in such a day ye look to the armor of the house of the forest;", "webster": "And he uncovered the coverings of Judah, and thou didst look in that day to the armor of the house of the forest.", "vulgate": "et revelabitur operimentum Iudae et videbis in die illa armamentarium domus saltus;", "brenton": "And they shall uncover the gates of Juda, and they shall look in that day on the choice houses of the city."}}, {"v": 9, "ref": "22:9", "o": "וְ/אֵ֨ת בְּקִיעֵ֧י עִיר דָּוִ֛ד רְאִיתֶ֖ם כִּי רָ֑בּוּ וַֽ/תְּקַבְּצ֔וּ אֶת מֵ֥י הַ/בְּרֵכָ֖ה הַ/תַּחְתּוֹנָֽה", "en": {"kjv": "Ye have seen also the breaches of the city of David, that they are many: and ye gathered together the waters of the lower pool.", "web": "You saw the breaches of the city of David, that they were many; and you gathered together the waters of the lower pool.", "bsb": "You saw that there were many breaches in the walls of the City of David. You collected water from the lower pool.", "asv": "And ye saw the breaches of the city of David, that they were many; and ye gathered together the waters of the lower pool;", "ylt": "And the breaches of the city of David ye have seen, For they have become many, And ye gather the waters of the lower pool,", "dra": "And you shall see the breaches of the city of David, that they are many: and you have gathered together the waters of the lower pool,", "bbe": "And you saw all the broken places in the wall of the town of David: and you got together the waters of the lower pool.", "geneva": "And ye haue seene the breaches of the citie of Dauid: for they were many, and ye gathered the waters of the lower poole.", "wycliffe": "and ye schulen se the crasyngis of the citee of Dauid, for tho ben multiplied. Ye gaderiden togidere the watris of the lowere cisterne,", "rotherham": "And the breaches in the city of David, ye beheld for they were many,—So ye gathered together the waters of the lower pool;", "darby": "and ye have seen the breaches of the city of David, that they are many; and ye have gathered together the waters of the lower pool;", "twenty": "", "jps": "And ye saw the breaches of the city of David, that they were many; and ye gathered together the waters of the lower pool.", "acv": "And ye saw the breaches of the city of David, that they were many. And to fortify the wall, ye gathered together the waters of the lower pool,", "anderson": "", "haweis": "", "noyes": "Ye mark how many are the breaches of the city of David, And collect the waters of the lower pool;", "webster": "Ye have seen also the breaches of the city of David, that they are many: and ye collected the waters of the lower pool.", "vulgate": "et scissuras civitatis David videbitis quia multiplicatae sunt et congregastis aquas piscinae inferioris;", "brenton": "And they shall uncover the secret places of the houses of the citadel of David: and they saw that they were many, and that one had turned the water of the old pool into the city;"}}, {"v": 10, "ref": "22:10", "o": "וְ/אֶת בָּתֵּ֥י יְרוּשָׁלִַ֖ם סְפַרְתֶּ֑ם וַ/תִּתְֿצוּ֙ הַ/בָּ֣תִּ֔ים לְ/בַצֵּ֖ר הַ/חוֹמָֽה", "en": {"kjv": "And ye have numbered the houses of Jerusalem, and the houses have ye broken down to fortify the wall.", "web": "You numbered the houses of Jerusalem, and you broke down the houses to fortify the wall.", "bsb": "You counted the houses of Jerusalem and tore them down to strengthen the wall.", "asv": "and ye numbered the houses of Jerusalem, and ye brake down the houses to fortify the wall;", "ylt": "And the houses of Jerusalem ye did number, And ye break down the houses to fence the wall.", "dra": "And have numbered the houses of Jerusalem, and broken down houses to fortify the wall.", "bbe": "And you had the houses of Jerusalem numbered, pulling down the houses to make the wall stronger.", "geneva": "And yee nombred the houses of Ierusalem, and the houses haue yee broken downe to fortifie the wall,", "wycliffe": "and ye noumbriden the housis of Jerusalem, and ye distrieden housis, to make strong the wal; and ye maden a lake bitwixe twei wallis,", "rotherham": "And the houses of Jerusalem, ye counted,—And brake down the houses, to fortify the wall;", "darby": "and ye have numbered the houses of Jerusalem, and have broken down the houses to fortify the wall;", "twenty": "", "jps": "And ye numbered the houses of Jerusalem, and ye broke down the houses to fortify the wall;", "acv": "and ye numbered the houses of Jerusalem, and ye broke down the houses.", "anderson": "", "haweis": "", "noyes": "Ye number the houses of Jerusalem, And ye break down the houses to prepare the wall;", "webster": "And ye have numbered the houses of Jerusalem, and the houses have ye broken down to fortify the wall.", "vulgate": "et domos Hierusalem numerastis et destruxistis domos ad muniendum murum;", "brenton": "and that they had pulled down the houses of Jerusalem, to fortify the wall of the city."}}, {"v": 11, "ref": "22:11", "o": "וּ/מִקְוָ֣ה עֲשִׂיתֶ֗ם בֵּ֚ין הַ/חֹ֣מֹתַ֔יִם לְ/מֵ֖י הַ/בְּרֵכָ֣ה הַ/יְשָׁנָ֑ה וְ/לֹ֤א הִבַּטְתֶּם֙ אֶל עֹשֶׂ֔י/הָ וְ/יֹצְרָ֥/הּ מֵֽ/רָח֖וֹק לֹ֥א רְאִיתֶֽם", "en": {"kjv": "Ye made also a ditch between the two walls for the water of the old pool: but ye have not looked unto the maker thereof, neither had respect unto him that fashioned it long ago.", "web": "You also made a reservoir between the two walls for the water of the old pool. But you didn’t look to him who had done this, neither did you have respect for him who purposed it long ago.", "bsb": "You built a reservoir between the walls for the waters of the ancient pool, but you did not look to the One who made it, or consider Him who planned it long ago.", "asv": "ye made also a reservoir between the two walls for the water of the old pool. But ye looked not unto him that had done this, neither had ye respect unto him that purposed it long ago.", "ylt": "And a ditch ye made between the two walls, For the waters of the old pool, And ye have not looked unto its Maker, And its Framer of old ye have not seen.", "dra": "And you made a ditch between the two walls for the water of the old pool: and you have not looked up to the maker thereof, nor regarded him even at a distance, that wrought it long ago.", "bbe": "And you made a place between the two walls for storing the waters of the old pool: but you gave no thought to him who had done this, and were not looking to him by whom it had been purposed long before.", "geneva": "And haue also made a ditche betweene the two walles, for the waters of the olde poole, and haue not looked vnto the maker thereof, neither had respect vnto him that formed it of olde.", "wycliffe": "and ye restoriden the watir of the elde sisterne; and ye biholden not to hym, that made `thilke Jerusalem, and ye sien not the worchere therof afer.", "rotherham": "And a reservoir, ye made between the two walls, for the waters of the ancient pool,—And had no regard unto him that made it, Nor unto him that formed it long ago, had ye respect.", "darby": "and ye have made a reservoir between the two walls for the water of the old pool: but ye have not had regard unto the maker thereof, neither have ye looked unto him that fashioned it long ago.", "twenty": "", "jps": "ye made also a basin between the two walls for the water of the old pool--but ye looked not unto Him that had done this, neither had ye respect unto Him that fashioned it long ago.", "acv": "Ye also made a reservoir between the two walls for the water of the old pool. But ye did not look to him who had done this, nor had ye respect to him who purposed it long ago.", "anderson": "", "haweis": "", "noyes": "Ye make a reservoir between the two walls for the waters of the old pool; But ye look not to Him who hath done this; Ye regard not Him that hath prepared this from afar.", "webster": "Ye made also a ditch between the two walls for the water of the old pool: but ye have not looked to its maker, neither had respect to him that fashioned it long ago.", "vulgate": "et lacum fecistis inter duos muros et aquam piscinae veteris et non suspexistis ad eum qui fecerat eam et operatorem eius de longe non vidistis;", "brenton": "And ye procured to yourselves water between the two walls within the ancient pool: but ye looked not to him that made it from the beginning, and regarded not him that created it."}}, {"v": 12, "ref": "22:12", "o": "וַ/יִּקְרָ֗א אֲדֹנָ֧/י יְהוִ֛ה צְבָא֖וֹת בַּ/יּ֣וֹם הַ/ה֑וּא לִ/בְכִי֙ וּ/לְ/מִסְפֵּ֔ד וּ/לְ/קָרְחָ֖ה וְ/לַ/חֲגֹ֥ר שָֽׂק", "en": {"kjv": "And in that day did the Lord God of hosts call to weeping, and to mourning, and to baldness, and to girding with sackcloth:", "web": "In that day, the Lord, Yahweh of Armies, called to weeping, and to mourning, and to baldness, and to dressing in sackcloth:", "bsb": "On that day the Lord GOD of Hosts called for weeping and wailing, for shaven heads and the wearing of sackcloth.", "asv": "And in that day did the Lord, Jehovah of hosts, call to weeping, and to mourning, and to baldness, and to girding with sackcloth:", "ylt": "And call doth the Lord, Jehovah of Hosts, In that day, to weeping and to lamentation, And to baldness and to girding on of sackcloth,", "dra": "And the Lord, the God of hosts, in that day shall call to weeping, and to mourning, to baldness, and to girding with sackcloth:", "bbe": "And in that day the Lord, the Lord of armies, was looking for weeping, and cries of sorrow, cutting off of the hair, and putting on the clothing of grief:", "geneva": "And in that day did the Lord God of hosts call vnto weeping and mourning, and to baldnes and girding with sackecloth.", "wycliffe": "And the Lord God of oostis schal clepe in that dai to wepyng, and to morenyng, and to ballidnesse, and to a girdil of sak; and lo!", "rotherham": "And, when My Lord Yahweh of hosts called in that day,—for weeping, and for lamentation, and for shaving bare and for girding with sackcloth,", "darby": "And in that day did the Lord Jehovah of hosts call to weeping, and to mourning, and to baldness, and to girding with sackcloth;", "twenty": "", "jps": "And in that day did the L-rd, the GOD of hosts, call to weeping, and to lamentation, and to baldness, and to girding with sackcloth;", "acv": "And in that day the Lord, Jehovah of hosts, called for weeping, and for mourning, and for baldness, and for girding with sackcloth.", "anderson": "", "haweis": "", "noyes": "The Lord, Jehovah of hosts, calleth you this day To weeping and to lamentation, To baldness and to girding with sackcloth.", "webster": "And in that day did the Lord GOD of hosts call to weeping, and to mourning, and to baldness, and to girding with sackcloth:", "vulgate": "et vocavit Dominus Deus exercituum in die illa ad fletum et ad planctum ad calvitium et ad cingulum sacci;", "brenton": "And the Lord, the Lord of hosts, called in that day for weeping, and lamentation, and baldness, and for girding with sackcloth:"}}, {"v": 13, "ref": "22:13", "o": "וְ/הִנֵּ֣ה שָׂשׂ֣וֹן וְ/שִׂמְחָ֗ה הָרֹ֤ג בָּקָר֙ וְ/שָׁחֹ֣ט צֹ֔אן אָכֹ֥ל בָּשָׂ֖ר וְ/שָׁת֣וֹת יָ֑יִן אָכ֣וֹל וְ/שָׁת֔וֹ כִּ֥י מָחָ֖ר נָמֽוּת", "en": {"kjv": "And behold joy and gladness, slaying oxen, and killing sheep, eating flesh, and drinking wine: let us eat and drink; for to morrow we shall die.", "web": "and behold, joy and gladness, killing cattle and killing sheep, eating flesh and drinking wine: “Let us eat and drink, for tomorrow we will die.”", "bsb": "But look, there is joy and gladness, butchering of cattle and slaughtering of sheep, eating of meat and drinking of wine: “Let us eat and drink, for tomorrow we die!”", "asv": "and, behold, joy and gladness, slaying oxen and killing sheep, eating flesh and drinking wine: Let us eat and drink, for to-morrow we shall die.", "ylt": "And lo, joy and gladness, slaying of oxen, And slaughtering of sheep, Eating of flesh, and drinking of wine, Eat and drink, for to-morrow we die.", "dra": "And behold joy and gladness, killing calves, and slaying rams, eating flesh, and drinking wine: Let us eat and drink; for to morrow we shall die.", "bbe": "But in place of these there was joy and delight, oxen and sheep were being made ready for food, there was feasting and drinking: men said, Now is the time for food and wine, for tomorrow death comes.", "geneva": "And beholde, ioy and gladnes, slaying oxen and killing sheepe, eating flesh, and drinking wine, eating and drinking: for to morowe we shall die.", "wycliffe": "ioie and gladnesse is to sle caluys, and to strangle wetheris, to ete fleisch, and to drynke wyn; ete we, and drynke we, for we schulen die to morewe.", "rotherham": "Then lo! joy and rejoicing, killing oxen and slaughtering sheep, eating flesh and drinking wine,—Let us eat and drink, For to-morrow, we may die!", "darby": "and behold joy and rejoicing, slaying oxen, and killing sheep, eating flesh, and drinking wine: — Let us eat and drink, for to-morrow we die.", "twenty": "", "jps": "And behold joy and gladness, slaying oxen and killing sheep, eating flesh and drinking wine--' Let us eat and drink, for tomorrow we shall die!'", "acv": "And, behold, joy and gladness, slaying oxen and killing sheep, eating flesh and drinking wine. Let us eat and drink, for tomorrow we shall die.", "anderson": "", "haweis": "", "noyes": "But, behold, joy and gladness, Slaying oxen and killing sheep, Eating flesh and drinking wine! \"Let us eat and drink, For to-morrow we die!\"", "webster": "And behold joy and gladness, slaying oxen, and killing sheep, eating flesh, and drinking wine: let us eat and drink; for to-morrow we shall die.", "vulgate": "et ecce gaudium et laetitia occidere vitulos et iugulare arietes comedere carnes et bibere vinum comedamus et bibamus cras enim moriemur;", "brenton": "but they engaged in joy and gladness, slaying calves, and killing sheep, so as to eat flesh, and drink wine; saying, Let us eat and drink; for to-morrow we die."}}, {"v": 14, "ref": "22:14", "o": "וְ/נִגְלָ֥ה בְ/אָזְנָ֖/י יְהוָ֣ה צְבָא֑וֹת אִם יְ֠כֻפַּר הֶ/עָוֺ֨ן הַ/זֶּ֤ה לָ/כֶם֙ עַד תְּמֻת֔וּ/ן אָמַ֛ר אֲדֹנָ֥/י יְהוִ֖ה צְבָאֽוֹת", "en": {"kjv": "And it was revealed in mine ears by the Lord of hosts, Surely this iniquity shall not be purged from you till ye die, saith the Lord God of hosts.", "web": "Yahweh of Armies revealed himself in my ears, “Surely this iniquity will not be forgiven you until you die,” says the Lord, Yahweh of Armies.", "bsb": "The LORD of Hosts has revealed in my hearing: “Until your dying day, this sin of yours will never be atoned for,” says the Lord GOD of Hosts.", "asv": "And Jehovah of hosts revealed himself in mine ears, Surely this iniquity shall not be forgiven you till ye die, saith the Lord, Jehovah of hosts.", "ylt": "And revealed it hath been in mine ears, By Jehovah of Hosts: Not pardoned is this iniquity to you, Till ye die, said the Lord, Jehovah of Hosts.", "dra": "And the voice of the Lord of hosts was revealed in my ears: Surely this iniquity shall not be forgiven you till you die, saith the Lord God of hosts.", "bbe": "And the Lord of armies said to me secretly, Truly, this sin will not be taken from you till your death, says the Lord, the Lord of armies.", "geneva": "And it was declared in ye eares of the Lord of hostes. Surely this iniquitie shall not be purged from you, til ye die, saith the Lord God of hostes.", "wycliffe": "And the vois of the Lord of oostis is schewid in myn eeris, This wickidnesse schal not be foryouun to you, til ye dien, seith the Lord God of oostis.", "rotherham": "Therefore did Yahweh reveal himself in mine ears. Surely there shall be no propitiatory-covering put over this iniquity for you until ye die, Saith My Lord Yahweh of hosts.", "darby": "And it was revealed in mine ears by Jehovah of hosts: Assuredly this iniquity shall not be purged from you till ye die, saith the Lord, Jehovah of hosts.", "twenty": "", "jps": "And HaShem of hosts revealed Himself in mine ears: Surely this iniquity shall not be expiated by you till ye die, saith the L-rd, the GOD of hosts.", "acv": "And Jehovah of hosts revealed himself in my ears, Surely this iniquity shall not be forgiven you till ye die, says the Lord, Jehovah of hosts.", "anderson": "", "haweis": "", "noyes": "Therefore it hath been revealed in my ears by Jehovah of hosts; \"This iniquity shall not be forgiven you, till ye die,\" Saith the Lord, Jehovah of hosts.", "webster": "And it was revealed in my ears by the LORD of hosts, Surely this iniquity shall not be purged from you till ye die, saith the Lord GOD of hosts.", "vulgate": "et revelata est in auribus meis Domini exercituum si dimittetur iniquitas haec vobis donec moriamini dicit Dominus Deus exercituum;", "brenton": "And these things are revealed in the ears of the Lord of hosts: for this sin shall not be forgiven you, until ye die."}}, {"v": 15, "ref": "22:15", "o": "כֹּ֥ה אָמַ֛ר אֲדֹנָ֥/י יְהוִ֖ה צְבָא֑וֹת לֶךְ בֹּא֙ אֶל הַ/סֹּכֵ֣ן הַ/זֶּ֔ה עַל שֶׁבְנָ֖א אֲשֶׁ֥ר עַל הַ/בָּֽיִת", "en": {"kjv": "Thus saith the Lord God of hosts, Go, get thee unto this treasurer, even unto Shebna, which is over the house, and say,", "web": "Thus says the Lord, Yahweh of Armies, “Go, get yourself to this treasurer, even to Shebna, who is over the house, and say,", "bsb": "This is what the Lord GOD of Hosts says: “Go, say to Shebna, the steward in charge of the palace:", "asv": "Thus saith the Lord, Jehovah of hosts, Go, get thee unto this treasurer, even unto Shebna, who is over the house, and say,", "ylt": "Thus said the Lord, Jehovah of Hosts: `Go, enter in unto this steward, Unto Shebna, who is over the house:", "dra": "Thus saith the Lord God of hosts: Go, get thee in to him that dwelleth in the tabernacle, to Sobna who is over the temple: and thou shalt say to him:", "bbe": "The Lord, the Lord of armies, says, Go to this person in authority, this Shebna, who is over the house; who has made himself a resting-place on high, cutting out a place for himself in the rock, and say,", "geneva": "Thus sayeth the Lord God of hostes, Goe, get thee to that treasurer, to Shebna, the steward of the house, and say,", "wycliffe": "The Lord God of oostis seith these thingis, Go thou, and entre to hym that dwellith in the tabernacle, to Sobna, the souereyn of the temple; and thou schalt seie to hym,", "rotherham": "Thus, said My Lord Yahweh, of hosts, Come go in unto this steward, Unto Shebna, who is over the house:", "darby": "Thus saith the Lord Jehovah of hosts: Go, get thee in unto this steward, unto Shebna, who is over the house, [and say,]", "twenty": "", "jps": "Thus saith the L-rd, the GOD of hosts: Go, get thee unto this steward, even unto Shebna, who is over the house:", "acv": "Thus says the Lord, Jehovah of hosts, Go, get thee to this treasurer, even to Shebna, who is over the house, and say,", "anderson": "", "haweis": "", "noyes": "Thus saith the Lord, Jehovah of hosts: Go in to this steward, To Shebna, who is over the household, and say,", "webster": "Thus saith the Lord GOD of hosts, Go, repair to this treasurer, [even] to Shebna, who [is] over the house, [and say],", "vulgate": "haec dicit Dominus Deus exercituum vade ingredere ad eum qui habitat in tabernaculo ad Sobnam praepositum templi;", "brenton": "Thus saith the Lord of hosts, Go into the chamber, to Somnas the treasurer, and say to him, Why art thou here?"}}, {"v": 16, "ref": "22:16", "o": "מַה לְּ/ךָ֥ פֹה֙ וּ/מִ֣י לְ/ךָ֣ פֹ֔ה כִּֽי חָצַ֧בְתָּ לְּ/ךָ֛ פֹּ֖ה קָ֑בֶר חֹצְבִ֤י מָרוֹם֙ קִבְר֔/וֹ חֹקְקִ֥י בַ/סֶּ֖לַע מִשְׁכָּ֥ן לֽ/וֹ", "en": {"kjv": "What hast thou here? and whom hast thou here, that thou hast hewed thee out a sepulchre here, as he that heweth him out a sepulchre on high, and that graveth an habitation for himself in a rock?", "web": "‘What are you doing here? Who has you here, that you have dug out a tomb here?’ Cutting himself out a tomb on high, chiseling a habitation for himself in the rock!”", "bsb": "What are you doing here, and who authorized you to carve out a tomb for yourself here—to chisel your tomb in the height and cut your resting place in the rock?", "asv": "What doest thou here? and whom hast thou here, that thou hast hewed thee out here a sepulchre? hewing him out a sepulchre on high, graving a habitation for himself in the rock!", "ylt": "What--to thee here? And who--to thee here? That thou hast hewn out to thee here--a sepulchre? Hewing on high his sepulchre, Graving in a rock a dwelling for himself.", "dra": "What dost thou here, or as if thou wert somebody here? for thou hast hewed thee out a sepulchre here, thou hast hewed out a monument carefully in a high place, a dwelling for thyself in a rock.", "bbe": "Who are you, and by what right have you made for yourself a resting-place here?", "geneva": "What haste thou to doe here? and whome hast thou here? that thou shouldest here hewe thee out a sepulchre, as he that heweth out his sepulchre in an hie place, or that graueth an habitation for him selfe in a rocke?", "wycliffe": "What thou here, ethir as who here? for thou hast hewe to thee a sepulcre here, thou hast hewe a memorial in hiy place diligentli, a tabernacle in a stoon to thee.", "rotherham": "What doest thou here? And whom hast thou here? That thou hast hewn for thyself here a sepulchre,—As one hewing on high his sepulchre, Cutting out in the cliff a habitation for himself?", "darby": "What hast thou here? and whom hast thou here, that thou hast hewn thee out a sepulchre here, [as] he that heweth out his sepulchre on high, cutting out in the rock a habitation for himself?", "twenty": "", "jps": "What hast thou here, and whom hast thou here, that thou hast hewed thee out here a sepulchre, thou that hewest thee out a sepulchre on high, and gravest a habitation for thyself in the rock?", "acv": "What are thou doing here? And whom have thou here, that thou have hewed thee out here a sepulcher? Hewing him out a sepulcher on high, carving a habitation for himself in the rock!", "anderson": "", "haweis": "", "noyes": "What hast thou here, and whom hast thou here, That thou here hewest thee out a sepulchre,—That thou hewest out thy sepulchre on high, And gravest out a habitation for thyself in the rock?", "webster": "What hast thou here? and whom hast thou here, that thou hast hewed thee out a sepulcher here, [as] he that heweth him out a sepulcher on high, [and] that graveth a habitation for himself in a rock?", "vulgate": "quid tu hic aut quasi quis hic quia excidisti tibi hic sepulchrum excidisti in excelso memoriam diligenter in petra tabernaculum tibi;", "brenton": "and what hast thou to do here, that thou hast here hewn thyself a sepulchre, and madest thyself a sepulchre on high, and hast graven for thyself a dwelling in the rock?"}}, {"v": 17, "ref": "22:17", "o": "הִנֵּ֤ה יְהוָה֙ מְטַלְטֶלְ/ךָ֔ טַלְטֵלָ֖ה גָּ֑בֶר וְ/עֹטְ/ךָ֖ עָטֹֽה", "en": {"kjv": "Behold, the Lord will carry thee away with a mighty captivity, and will surely cover thee.", "web": "Behold, Yahweh will overcome you and hurl you away violently. Yes, he will grasp you firmly.", "bsb": "Look, O mighty man! The LORD is about to shake you violently. He will take hold of you,", "asv": "Behold, Jehovah, like a strong man, will hurl thee away violently; yea, he will wrap thee up closely.", "ylt": "Lo, Jehovah is casting thee up and down, A casting up and down, O mighty one,", "dra": "Behold the Lord will cause thee to be carried away, as a cock is carried away, and he will lift thee up as a garment.", "bbe": "See, O strong man, the Lord will send you violently away, gripping you with force,", "geneva": "Beholde, the Lord wil carie thee away with a great captiuitie, and will surely couer thee.", "wycliffe": "Lo! the Lord schal make thee to be borun out, as a kapoun is borun out, and as a cloth, so he shal reise thee.", "rotherham": "Lo! Yahweh, is about to hurl thee, with a hurl, O mighty man,—And roll thee with a roll;", "darby": "Behold, Jehovah will hurl thee with the force of a mighty man, and will cover thee entirely.", "twenty": "", "jps": "Behold, HaShem will hurl thee up and down with a man's throw; yea, He will wind thee round and round;", "acv": "Behold, Jehovah, like a strong man, will hurl thee away violently. Yea, he will wrap thee up closely.", "anderson": "", "haweis": "", "noyes": "Behold, Jehovah will cast thee headlong with a mighty thrust;", "webster": "Behold, the LORD will carry thee away with a mighty captivity, and will surely cover thee.", "vulgate": "ecce Dominus asportari te faciet sicut asportatur gallus gallinacius et quasi amictum sic sublevabit te;", "brenton": "Behold now, the Lord of hosts casts forth and will utterly destroy such a man, and will take away thy robe and thy glorious crown,"}}, {"v": 18, "ref": "22:18", "o": "צָנ֤וֹף יִצְנָפְ/ךָ֙ צְנֵפָ֔ה כַּדּ֕וּר אֶל אֶ֖רֶץ רַחֲבַ֣ת יָדָ֑יִם שָׁ֣מָּ/ה תָמ֗וּת וְ/שָׁ֨מָּ/ה֙ מַרְכְּב֣וֹת כְּבוֹדֶ֔/ךָ קְל֖וֹן בֵּ֥ית אֲדֹנֶֽי/ךָ", "en": {"kjv": "He will surely violently turn and toss thee like a ball into a large country: there shalt thou die, and there the chariots of thy glory shall be the shame of thy lord’s house.", "web": "He will surely wind you around and around, and throw you like a ball into a large country. There you will die, and there the chariots of your glory will be, you shame of your lord’s house.", "bsb": "roll you into a ball, and sling you into a wide land. There you will die, and there your glorious chariots will remain—a disgrace to the house of your master.", "asv": "He will surely wind thee round and round, and toss thee like a ball into a large country; there shalt thou die, and there shall be the chariots of thy glory, thou shame of thy lord’s house.", "ylt": "And thy coverer covering, wrapping round, Wrappeth thee round, O babbler, On a land broad of sides--there thou diest, And there the chariots of thine honour Are the shame of the house of thy lord.", "dra": "He will crown thee with a crown of tribulation, he will toss thee like a ball into a large and spacious country: there shalt thou die, and there shall the chariot of thy glory be, the shame of the house of thy Lord.", "bbe": "Twisting you round and round like a ball he will send you out into a wide country: there you will come to your end, and there will be the carriages of your pride, O shame of your lord's house!", "geneva": "He wil surely rolle and turne thee like a bal in a large countrey: there shalt thou die, and there the charets of thy glory shalbe the shame of thy lordes house.", "wycliffe": "He crowninge schal crowne thee with tribulacioun; he schal sende thee as a bal in to a large lond and wijd; there thou schalt die, and there schal be the chare of thi glorie, and the schenschipe of the hous of thi Lord.", "rotherham": "He will, toss, thee, with a toss, like a ball, into a country wide on both hands,—There, shalt thou die, And there shall thy glorious chariots be the contempt of the house of thy lord.", "darby": "Rolling thee up completely, he will roll thee as a ball into a wide country: there shalt thou die, and there shall be the chariots of thy glory, O shame of thy lord's house!", "twenty": "", "jps": "He will violently roll and toss thee like a ball into a large country; there shalt thou die, and there shall be the chariots of thy glory, thou shame of the lord's house.", "acv": "He will surely wind thee round and round, tossing like a ball into a large country. There thou shall die, and there the chariots of thy glory shall be, thou shame of thy lord's house.", "anderson": "", "haweis": "", "noyes": "He will violently roll thee together like a ball; Like a ball will he hurl thee into a wide country. There shalt thou die; And there shall be thy splendid chariots, Thou disgrace of the house of thy lord!", "webster": "With violence he will surely turn and toss thee [like] a ball into a wide country: there shalt thou die, and there the chariots of thy glory [shall be] the shame of thy lord's house.", "vulgate": "coronans coronabit te tribulatione quasi pilam mittet te in terram latam et spatiosam ibi morieris et ibi erit currus gloriae tuae ignominia domus Domini tui;", "brenton": "and will cast thee into a great and unmeasured land, and there thou shalt die: and he will bring thy fair chariot to shame, and the house of thy prince to be trodden down."}}, {"v": 19, "ref": "22:19", "o": "וַ/הֲדַפְתִּ֖י/ךָ מִ/מַּצָּבֶ֑/ךָ וּ/מִ/מַּעֲמָֽדְ/ךָ֖ יֶהֶרְסֶֽ/ךָ", "en": {"kjv": "And I will drive thee from thy station, and from thy state shall he pull thee down.", "web": "I will thrust you from your office. You will be pulled down from your station.", "bsb": "I will remove you from office, and you will be ousted from your position.", "asv": "And I will thrust thee from thine office; and from thy station shalt thou be pulled down.", "ylt": "And I have thrust thee from thy station, And from thine office he throweth thee down.", "dra": "And I will drive thee out from thy station, and depose thee from thy ministry.", "bbe": "And I will have you forced out of your place of authority, and pulled down from your position.", "geneva": "And I wil driue thee from thy station, and out of thy dwelling will he destroy thee.", "wycliffe": "And Y schal caste thee out of thi stondyng, and Y schal putte thee doun of thi seruyce.", "rotherham": "Thus will I thrust thee out from thine office,—And from thy station, shall one tear thee down.", "darby": "And I will drive thee from thine office, and from thy station will I pull thee down.", "twenty": "", "jps": "And I will thrust thee from thy post, and from thy station shalt thou be pulled down.", "acv": "And I will thrust thee from thine office, and thou shall be pulled down from thy station.", "anderson": "", "haweis": "", "noyes": "I will drive thee from thy post, And from thy station I will pull thee down.", "webster": "And I will drive thee from thy station, and from thy state shall he pull thee down.", "vulgate": "et expellam te de statione tua et de ministerio tuo deponam te;", "brenton": "And thou shalt be removed from thy stewardship, and from thy place."}}, {"v": 20, "ref": "22:20", "o": "וְ/הָיָ֖ה בַּ/יּ֣וֹם הַ/ה֑וּא וְ/קָרָ֣אתִי לְ/עַבְדִּ֔/י לְ/אֶלְיָקִ֖ים בֶּן חִלְקִיָּֽהוּ", "en": {"kjv": "And it shall come to pass in that day, that I will call my servant Eliakim the son of Hilkiah:", "web": "It will happen in that day that I will call my servant Eliakim the son of Hilkiah,", "bsb": "On that day I will summon My servant, Eliakim son of Hilkiah.", "asv": "And it shall come to pass in that day, that I will call my servant Eliakim the son of Hilkiah:", "ylt": "And it hath come to pass, in that day, That I have called to my servant, To Eliakim son of Hilkiah.", "dra": "And it shall come to pass in that day, that I will call my servant Eliacim the son of Helcias,", "bbe": "And in that day I will send for my servant, Eliakim, the son of Hilkiah:", "geneva": "And in that day will I call my seruant Eliakim the sonne of Hilkiah,", "wycliffe": "And it schal be, in that dai Y schal clepe my seruaunt Eliachim, the sone of Helchie; and Y schal clothe hym in thi coote,", "rotherham": "And it shall come to pass in that day, That I will call for my servant, for Eliakim son of Hilkiah,", "darby": "And it shall come to pass in that day, that I will call my servant Eliakim the son of Hilkijah;", "twenty": "", "jps": "And it shall come to pass in that day, that I will call my servant Eliakim the son of Hilkiah;", "acv": "And it shall come to pass in that day, that I will call my servant Eliakim the son of Hilkiah.", "anderson": "", "haweis": "", "noyes": "In that day I will call my servant, Even Eliakim, the son of Hilkiah;", "webster": "And it shall come to pass in that day, that I will call my servant Eliakim the son of Hilkiah:", "vulgate": "et erit in die illa vocabo servum meum Eliachim filium Helciae;", "brenton": "And it shall come to pass in that day, that I will call my servant Eliakim the son of Chelcias:"}}, {"v": 21, "ref": "22:21", "o": "וְ/הִלְבַּשְׁתִּ֣י/ו כֻּתָּנְתֶּ֗/ךָ וְ/אַבְנֵֽטְ/ךָ֙ אֲחַזְּקֶ֔/נּוּ וּ/מֶֽמְשֶׁלְתְּ/ךָ֖ אֶתֵּ֣ן בְּ/יָד֑/וֹ וְ/הָיָ֥ה לְ/אָ֛ב לְ/יוֹשֵׁ֥ב יְרוּשָׁלִַ֖ם וּ/לְ/בֵ֥ית יְהוּדָֽה", "en": {"kjv": "And I will clothe him with thy robe, and strengthen him with thy girdle, and I will commit thy government into his hand: and he shall be a father to the inhabitants of Jerusalem, and to the house of Judah.", "web": "and I will clothe him with your robe, and strengthen him with your belt. I will commit your government into his hand; and he will be a father to the inhabitants of Jerusalem, and to the house of Judah.", "bsb": "I will clothe him with your robe and tie your sash around him. I will put your authority in his hand, and he will be a father to the dwellers of Jerusalem and to the house of Judah.", "asv": "and I will clothe him with thy robe, and strengthen him with thy girdle, and I will commit thy government into his hand; and he shall be a father to the inhabitants of Jerusalem, and to the house of Judah.", "ylt": "And I have clothed him with thy coat, And with thy girdle I strengthen him, And thy garment I give into his hand, And he hath been for a father to the inhabitant of Jerusalem, And to the house of Judah.", "dra": "And I will clothe him with thy robe, and will strengthen him with thy girdle, and will give thy power into his hand: and he shall be as a father to the inhabitants of Jerusalem, and to the house of Juda.", "bbe": "And I will put your robe on him, and put your band about him, and I will give your authority into his hand: and he will be a father to the men of Jerusalem, and to the family of Judah.", "geneva": "And with thy garments will I clothe him, and with thy girdle will I strengthen him: thy power also will I commit into his hande, and hee shalbe a father of the inhabitats of Ierusalem, and of the house of Iudah.", "wycliffe": "and Y schal coumforte hym with thi girdil, and Y shal yyue thi power in to the hondis of hym; and he schal be as a fadir to hem that dwellen in Jerusalem, and to the hous of Juda.", "rotherham": "And will clothe him with thy tunic And with thy girdle, will I gird him, And thine authority, will I deliver into his hand,—So shall he become a father To the inhabitant of Jerusalem and To the house of Judah.", "darby": "and I will clothe him with thy robe, and strengthen him with thy girdle, and I will commit thy government into his hand; and he shall be a father to the inhabitants of Jerusalem, and to the house of Judah.", "twenty": "", "jps": "And I will clothe him with thy robe, and bind him with thy girdle, and I will commit thy government into his hand; and he shall be a father to the inhabitants of Jerusalem, and to the house of Judah.", "acv": "And I will clothe him with thy robe, and strengthen him with thy belt. And I will commit thy government into his hand, and he shall be a father to the inhabitants of Jerusalem, and to the house of Judah.", "anderson": "", "haweis": "", "noyes": "I will clothe him with thy robe, And bind thy girdle around him; Thy government will I commit to his hand, And he shall be a father to the inhabitants of Jerusalem, And to the house of Judah.", "webster": "And I will clothe him with thy robe, and strengthen him with thy girdle, and I will commit thy government into his hand: and he shall be a father to the inhabitants of Jerusalem, and to the house of Judah.", "vulgate": "et induam illum tunicam tuam et cingulo tuo confortabo eum et potestatem tuam dabo in manu eius et erit quasi pater habitantibus Hierusalem et domui Iuda;", "brenton": "and I will put on him thy robe, and I will grant him thy crown with power, and I will give thy stewardship into his hands: and he shall be as a father to them that dwell in Jerusalem, and to them that dwell in Juda."}}, {"v": 22, "ref": "22:22", "o": "וְ/נָתַתִּ֛י מַפְתֵּ֥חַ בֵּית דָּוִ֖ד עַל שִׁכְמ֑/וֹ וּ/פָתַח֙ וְ/אֵ֣ין סֹגֵ֔ר וְ/סָגַ֖ר וְ/אֵ֥ין פֹּתֵֽחַ", "en": {"kjv": "And the key of the house of David will I lay upon his shoulder; so he shall open, and none shall shut; and he shall shut, and none shall open.", "web": "I will lay the key of the house of David on his shoulder. He will open, and no one will shut. He will shut, and no one will open.", "bsb": "I will place on his shoulder the key to the house of David. What he opens no one can shut, and what he shuts no one can open.", "asv": "And the key of the house of David will I lay upon his shoulder; and he shall open, and none shall shut; and he shall shut, and none shall open.", "ylt": "And I have placed the key Of the house of David on his shoulder, And he hath opened, and none is shutting, And hath shut, and none is opening.", "dra": "And I will lay the key of the house of David upon his shoulder: and he shall open, and none shall shut: and he shall shut, and none shall open.", "bbe": "And I will give the key of the family of David into his care; and what he keeps open will be shut by no one, and what he keeps shut no one will make open.", "geneva": "And the key of the house of Dauid will I lay vpon his shoulder: so hee shall open, and no man shall shut: and he shall shut, and no man shall open.", "wycliffe": "And Y schal yyue the keie of the hous of Dauyd on his schuldre; and he schal opene, and noon schal be that schal schitte; and he schal schitte, and noon schal be that schal opene.", "rotherham": "And I will lay the key of the house of David upon his shoulder,—And he shall open and none shall shut, And shut and none shall open;", "darby": "And the key of the house of David will I lay upon his shoulder; and he shall open, and none shall shut; and he shall shut, and none shall open.", "twenty": "", "jps": "And the key of the house of David will I lay upon his shoulder; and he shall open, and none shall shut; and he shall shut, and none shall open.", "acv": "And I will lay the key of the house of David upon his shoulder, and he shall open, and none shall shut, and he shall shut, and none shall open.", "anderson": "", "haweis": "", "noyes": "I will lay the key of the house of David upon his shoulder; He shall open, and none shall shut, And he shall shut, and none shall open.", "webster": "And the key of the house of David will I lay upon his shoulder; so he shall open, and none shall shut; and he shall shut, and none shall open.", "vulgate": "et dabo clavem domus David super umerum eius et aperiet et non erit qui claudat et claudet et non erit qui aperiat;", "brenton": "And I will give him the glory of David; and he shall rule, and there shall be none to speak against him: and I will give him the key of the house of David upon his shoulder; and he shall open, and there shall be none to shut; and he shall shut, and there shall be none to open."}}, {"v": 23, "ref": "22:23", "o": "וּ/תְקַעְתִּ֥י/ו יָתֵ֖ד בְּ/מָק֣וֹם נֶאֱמָ֑ן וְ/הָיָ֛ה לְ/כִסֵּ֥א כָב֖וֹד לְ/בֵ֥ית אָבִֽי/ו", "en": {"kjv": "And I will fasten him as a nail in a sure place; and he shall be for a glorious throne to his father’s house.", "web": "I will fasten him like a nail in a sure place. He will be for a throne of glory to his father’s house.", "bsb": "I will drive him like a peg into a firm place, and he will be a throne of glory for the house of his father.", "asv": "And I will fasten him as a nail in a sure place; and he shall be for a throne of glory to his father’s house.", "ylt": "And I have fixed him a nail in a stedfast place, And he hath been for a throne of honour To the house of his father.", "dra": "And I will fasten him as a peg in a sure place, and he shall be for a throne of glory to the house of his father.", "bbe": "And I will put him like a nail in a safe place; and he will be for a seat of glory to his father's family.", "geneva": "And I will fasten him as a naile in a sure place, and hee shall be for the throne of glorie to his fathers house.", "wycliffe": "And Y schal sette hym a stake in a feithful place, and he schal be in to the seete of glorie of the hous of his fadir.", "rotherham": "And I will fasten him as a peg in a sure place,—And he shall become a throne of glory, to the house of his father;", "darby": "And I will fasten him [as] a nail in a sure place; and he shall be for a throne of glory to his father's house:", "twenty": "", "jps": "And I will fasten him as a peg in a sure place; and he shall be for a throne of honour to his father's house.", "acv": "And I will fasten him as a nail in a sure place, and he shall be for a throne of glory to his father's house.", "anderson": "", "haweis": "", "noyes": "I will fasten him as a peg in a sure place, And he shall be a glorious seat for his father’s house.", "webster": "And I will fasten him [as] a nail in a sure place; and he shall be for a glorious throne to his father's house.", "vulgate": "et figam illum paxillum in loco fideli et erit in solium gloriae domui patris sui;", "brenton": "And I will make him a ruler in a sure place, and he shall be for a glorious throne of his father's house."}}, {"v": 24, "ref": "22:24", "o": "וְ/תָל֨וּ עָלָ֜י/ו כֹּ֣ל כְּב֣וֹד בֵּית אָבִ֗י/ו הַ/צֶּֽאֱצָאִים֙ וְ/הַ/צְּפִע֔וֹת כֹּ֖ל כְּלֵ֣י הַ/קָּטָ֑ן מִ/כְּלֵי֙ הָֽ/אַגָּנ֔וֹת וְ/עַ֖ד כָּל כְּלֵ֥י הַ/נְּבָלִֽים", "en": {"kjv": "And they shall hang upon him all the glory of his father’s house, the offspring and the issue, all vessels of small quantity, from the vessels of cups, even to all the vessels of flagons.", "web": "They will hang on him all the glory of his father’s house, the offspring and the issue, every small vessel, from the cups even to all the pitchers.", "bsb": "So they will hang on him all the glory of his father’s house: the descendants and the offshoots—all the lesser vessels, from bowls to every kind of jar.", "asv": "And they shall hang upon him all the glory of his father’s house, the offspring and the issue, every small vessel, from the cups even to all the flagons.", "ylt": "And they have hanged on him All the honour of the house of his father, The offspring and the issue, All vessels of small quality, From vessels of basins to all vessels of flagons.", "dra": "And they shall hang upon him all the glory of his father's house, divers kinds of vessels, every little vessel, from the vessels of cups even to every instrument of music.", "bbe": "And all the glory of his father's family will be hanging on him, all their offspring, every small vessel, even the cups and the basins.", "geneva": "And they shall hang vpon him all the glorie of his fathers house, euen of the nephewes and posteritie all small vessels, from the vessels of the cuppes, euen to all the instruments of musike.", "wycliffe": "And thou schalt hange on hym al the glorie of the hous of his fadir, diuerse kindis of vessels, eche litil vessel, fro the vesselis of cuppis `til to ech vessel of musikis.", "rotherham": "And they shall hang upon him all the weight of his father’s house—The offshoots and the side-twigs—All the small vessels, Both the cups and all the jugs", "darby": "and they shall hang upon him all the glory of his father's house, the offspring and the issue, all the small vessels, as well the vessels of cups as all the vessels of flagons.", "twenty": "", "jps": "And they shall hang upon him all the glory of his father's house, the offspring and the issue, all vessels of small quantity, from the vessels of cups even to all the vessels of flagons.", "acv": "And they shall hang upon him all the glory of his father's house, the offspring and the issue, every small vessel, from the cups even to all the flagons.", "anderson": "", "haweis": "", "noyes": "Upon him shall hang all the glory of his father’s house, The offspring and the offshoots; Every small vessel, from the goblet even to all the pitchers.", "webster": "And they shall hang upon him all the glory of his father's house, the offspring and the issue, all vessels of small quantity, from the vessels of cups, even to all the vessels of flagons.", "vulgate": "et suspendent super eum omnem gloriam domus patris eius vasorum diversa genera omne vas parvulum a vasis craterarum usque ad omne vas musicorum;", "brenton": "And every one that is glorious in the house of his father shall trust in him, from the least to the greatest; and they shall depend upon him in that day."}}, {"v": 25, "ref": "22:25", "o": "בַּ/יּ֣וֹם הַ/ה֗וּא נְאֻם֙ יְהוָ֣ה צְבָא֔וֹת תָּמוּשׁ֙ הַ/יָּתֵ֔ד הַ/תְּקוּעָ֖ה בְּ/מָק֣וֹם נֶאֱמָ֑ן וְ/נִגְדְּעָ֣ה וְ/נָפְלָ֗ה וְ/נִכְרַת֙ הַ/מַּשָּׂ֣א אֲשֶׁר עָלֶ֔י/הָ כִּ֥י יְהוָ֖ה דִּבֵּֽר", "en": {"kjv": "In that day, saith the Lord of hosts, shall the nail that is fastened in the sure place be removed, and be cut down, and fall; and the burden that was upon it shall be cut off: for the Lord hath spoken it.", "web": "“In that day,” says Yahweh of Armies, “the nail that was fastened in a sure place will give way. It will be cut down, and fall. The burden that was on it will be cut off, for Yahweh has spoken it.”", "bsb": "In that day, declares the LORD of Hosts, the peg driven into a firm place will give way; it will be sheared off and fall, and the load upon it will be cut down.” Indeed, the LORD has spoken.", "asv": "In that day, saith Jehovah of hosts, shall the nail that was fastened in a sure place give way; and it shall be hewn down, and fall; and the burden that was upon it shall be cut off; for Jehovah hath spoken it.", "ylt": "In that day--an affirmation of Jehovah of Hosts, Moved is the nail that is fixed In a stedfast place, Yea, it hath been cut down, and hath fallen, And cut off hath been the burden that is on it, For Jehovah hath spoken!'", "dra": "In that day, saith the Lord of hosts, shall the peg be removed, that was fastened in the sure place: and it shall be broken and shall fall: and that which hung thereon, shall perish, because the Lord hath spoken it.", "bbe": "In that day, says the Lord of armies, will the nail fixed in a safe place give way; and it will be cut down, and in its fall the weight hanging on it will be cut off, for the Lord has said it.", "geneva": "In that day, sayeth the Lord of hostes, shall the naile, that is fastned in the sure place, depart and shall be broken, and fall: and the burden, that was vpon it, shall bee cut off: for the Lord hath spoken it.", "wycliffe": "In that dai, seith the Lord of oostis, the stake that was set in the feithful place, schal be takun awei, and it schal be brokun, and schal falle doun; and schal perische that hangide therynne, for the Lord spak.", "rotherham": "In that day,—Declareth Yahweh of hosts Shall the peg, give way, that was fastened in a sure place,—Yea it shall be cut off and fall And the burden that was upon it shall perish, For, Yahweh, hath spoken!", "darby": "In that day, saith Jehovah of hosts, shall the nail that is fastened in a sure place be removed, and be cut down, and fall; and the burden that was upon it shall be cut off: for Jehovah hath spoken.", "twenty": "", "jps": "In that day, saith HaShem of hosts, shall the peg that was fastened in a sure place give way; and it shall be hewn down, and fall, and the burden that was upon it shall be cut off; for HaShem hath spoken it.", "acv": "In that day, says Jehovah of hosts, the nail that was fastened in a sure place shall give way, and it shall be hewn down, and fall. And the burden that was upon it shall be cut off, for Jehovah has spoken it.", "anderson": "", "haweis": "", "noyes": "In that day, saith Jehovah of hosts, The peg that was once fastened in a sure place shall be moved; It shall be cut down, and fall, And the burden which was upon it shall come to the ground. For Jehovah hath said it.", "webster": "In that day, saith the LORD of hosts, shall the nail that is fastened in the sure place be removed, and be cut down, and fall; and the burden that [was] upon it shall be cut off: for the LORD hath spoken it.", "vulgate": "in die illo dicit Dominus exercituum auferetur paxillus qui fixus fuerat in loco fideli et frangetur et cadet et peribit quod pependerat in eo quia Dominus locutus est;", "brenton": "Thus saith the Lord of hosts, The man that is fastened in the sure place shall be removed and be taken away, and shall fall; and the glory that is upon him shall be utterly destroyed: for the Lord has spoken it."}}]}, {"c": 23, "verses": [{"v": 1, "ref": "23:1", "o": "מַשָּׂ֖א צֹ֑ר הֵילִ֣ילוּ אֳנִיּ֣וֹת תַּרְשִׁ֗ישׁ כִּֽי שֻׁדַּ֤ד מִ/בַּ֨יִת֙ מִ/בּ֔וֹא מֵ/אֶ֥רֶץ כִּתִּ֖ים נִגְלָה לָֽ/מוֹ", "en": {"kjv": "The burden of Tyre. Howl, ye ships of Tarshish; for it is laid waste, so that there is no house, no entering in: from the land of Chittim it is revealed to them.", "web": "The burden of Tyre. Howl, you ships of Tarshish! For it is laid waste, so that there is no house, no entering in. From the land of Kittim it is revealed to them.", "bsb": "This is the burden against Tyre: Wail, O ships of Tarshish, for Tyre is laid waste, without house or harbor. Word has reached them from the land of Cyprus.", "asv": "The burden of Tyre. Howl, ye ships of Tarshish; for it is laid waste, so that there is no house, no entering in: from the land of Kittim it is revealed to them.", "ylt": "The Burden of Tyre. Howl, ye ships of Tarshish, For it hath been destroyed, Without house, without entrance, From the land of Chittim it was revealed to them.", "dra": "The burden of Tyre. Howl, ye ships of the sea, for the house is destroyed, from whence they were wont to come: from the land of Cethim it is revealed to them.", "bbe": "The word about Tyre. Let a cry of sorrow go up, O ships of Tarshish, because your strong place is made waste; on the way back from the land of Kittim the news is given to them.", "geneva": "The burden of Tyrus. Howle, yee shippes of Tarshish: for it is destroied, so that there is none house: none shall come from the lande of Chittim: it is reueiled vnto them.", "wycliffe": "The birthun of Tire. Ye schippis of the see, yelle, for the hous is distried, fro whennus coumfort was wont to come; fro the lond of Cethym, and was schewid to hem.", "rotherham": "The oracle on Tyre,—Howl! ye ships of Tarshish, For it is laid too waste to be a haven to enter, From the land of Cyprus, hath it been unveiled to them.", "darby": "The burden of Tyre. Howl, ye ships of Tarshish! for it is laid waste, so that there is no house, none entering in. From the land of Chittim it is revealed to them.", "twenty": "", "jps": "The burden of Tyre. Howl, ye ships of Tarshish, for it is laid waste, so that there is no house, no entering in; from the land of Kittim it is revealed to them.", "acv": "The burden of Tyre. Howl, ye ships of Tarshish, for it is laid waste, so that there is no house, no entering in. It is revealed to them from the land of Kittim.", "anderson": "", "haweis": "", "noyes": "The prophecy concerning Tyre. Howl, ye ships of Tarshish! For it is laid waste; No house, no entrance is left! From the land of the Chittaeans were the tidings brought to them.", "webster": "The burden of Tyre. Howl, ye ships of Tarshish; for it is laid waste, so that there is no house, no entering in: from the land of Chittim it is revealed to them.", "vulgate": "onus Tyri ululate naves maris quia vastata est domus unde venire consueverant de terra Cetthim revelatum est eis;", "brenton": "THE WORD CONCERNING TYRE. Howl, ye ships of Carthage; for she has perished, and men no longer arrive from the land of the Citians: she is led captive."}}, {"v": 2, "ref": "23:2", "o": "דֹּ֖מּוּ יֹ֣שְׁבֵי אִ֑י סֹחֵ֥ר צִיד֛וֹן עֹבֵ֥ר יָ֖ם מִלְאֽוּ/ךְ", "en": {"kjv": "Be still, ye inhabitants of the isle; thou whom the merchants of Zidon, that pass over the sea, have replenished.", "web": "Be still, you inhabitants of the coast, you whom the merchants of Sidon, that pass over the sea, have replenished.", "bsb": "Be silent, O dwellers of the coastland, you merchants of Sidon, whose traders have crossed the sea.", "asv": "Be still, ye inhabitants of the coast, thou whom the merchants of Sidon, that pass over the sea, have replenished.", "ylt": "Be silent, ye inhabitants of the isle, Trader of Zidon, passing the sea, they filled thee.", "dra": "Be silent, you that dwell in the island: the merchants of Sidon passing over the sea, have filled thee.", "bbe": "Send out a cry of grief, you men of the sea-land, traders of Zidon, who go over the sea, whose representatives are on great waters;", "geneva": "Be still, yee that dwell in the yles: the marchantes of Zidon, and such as passe ouer the sea, haue replenished thee.", "wycliffe": "Be ye stille, that dwellen in the ile, the marchaundie of Sidon; men passynge the see filliden thee in many watris;", "rotherham": "Be dumb, ye inhabitants of the Coast,—Whom the merchants of Zidon, passing over the sea, once replenished;", "darby": "Be still, ye inhabitants of the isle! The merchants of Sidon, that pass over the sea, have replenished thee.", "twenty": "", "jps": "Be still, ye inhabitants of the coast-land; thou whom the merchants of Zidon, that pass over the sea, have replenished.", "acv": "Be still, ye inhabitants of the coast, thou whom the merchants of Sidon, who pass over the sea, have replenished.", "anderson": "", "haweis": "", "noyes": "Be amazed, ye inhabitants of the sea-coast, Which the merchants of Sidon, that pass over the sea, did crowd!", "webster": "Be still, ye inhabitants of the isle; thou whom the merchants of Zidon, that pass over the sea, have replenished.", "vulgate": "tacete qui habitatis in insula negotiatio Sidonis transfretantes mare repleverunt te;", "brenton": "To whom are the dwellers in the island become like, the merchants of Phoenice, passing over the sea"}}, {"v": 3, "ref": "23:3", "o": "וּ/בְ/מַ֤יִם רַבִּים֙ זֶ֣רַע שִׁחֹ֔ר קְצִ֥יר יְא֖וֹר תְּבֽוּאָתָ֑/הּ וַ/תְּהִ֖י סְחַ֥ר גּוֹיִֽם", "en": {"kjv": "And by great waters the seed of Sihor, the harvest of the river, is her revenue; and she is a mart of nations.", "web": "On great waters, the seed of the Shihor, the harvest of the Nile, was her revenue. She was the market of nations.", "bsb": "On the great waters came the grain of Shihor; the harvest of the Nile was the revenue of Tyre; she was the merchant of the nations.", "asv": "And on great waters the seed of the Shihor, the harvest of the Nile, was her revenue; and she was the mart of nations.", "ylt": "And in many waters is the seed of Sihor, The harvest of the brook is her increase, And she is a mart of nations.", "dra": "The seed of the Nile in many waters, the harvest of the river is her revenue: and she is become the mart of the nations.", "bbe": "Who get in the seed of Shihor, whose wealth is the trade of the nations.", "geneva": "The seede of Nilus growing by the abundance of waters, and the haruest of the riuer was her reuenues, and she was a marte of the nations.", "wycliffe": "the seed of Nylus is heruest, the flood is the corn therof, and it is maad the marchaundie of hethene men.", "rotherham": "Yea on mighty waters, was the grain of Shihor, The harvest of the Nile, was her increase,—And so she became a mart of nations.", "darby": "And on great waters, the seed of Shihor, the harvest of the Nile, was her revenue; and she was the market of the nations.", "twenty": "", "jps": "And on great waters the seed of Shihor, the harvest of the Nile, was her revenue; and she was the mart of nations.", "acv": "And on great waters the seed of the Shihor, the harvest of the Nile, was her revenue, and she was the mart of nations.", "anderson": "", "haweis": "", "noyes": "Upon the wide waters, the corn of the Nile, The harvest of the river, was her revenue; She was the mart of the nations.", "webster": "And by great waters the seed of Sihor, the harvest of the river, [is] her revenue; and she is a mart of nations.", "vulgate": "in aquis multis semen Nili messis fluminis fruges eius et facta est negotiatio gentium;", "brenton": "in great waters, a generation of merchants? as when the harvest is gathered in, so are these traders with the nations."}}, {"v": 4, "ref": "23:4", "o": "בּ֣וֹשִׁי צִיד֔וֹן כִּֽי אָמַ֣ר יָ֔ם מָע֥וֹז הַ/יָּ֖ם לֵ/אמֹ֑ר לֹֽא חַ֣לְתִּי וְ/לֹֽא יָלַ֗דְתִּי וְ/לֹ֥א גִדַּ֛לְתִּי בַּחוּרִ֖ים רוֹמַ֥מְתִּי בְתוּלֽוֹת", "en": {"kjv": "Be thou ashamed, O Zidon: for the sea hath spoken, even the strength of the sea, saying, I travail not, nor bring forth children, neither do I nourish up young men, nor bring up virgins.", "web": "Be ashamed, Sidon; for the sea has spoken, the stronghold of the sea, saying, “I have not travailed, nor given birth, neither have I nourished young men, nor brought up virgins.”", "bsb": "Be ashamed, O Sidon, the stronghold of the sea, for the sea has spoken: “I have not been in labor or given birth. I have not raised young men or brought up young women.”", "asv": "Be thou ashamed, O Sidon; for the sea hath spoken, the stronghold of the sea, saying, I have not travailed, nor brought forth, neither have I nourished young men, nor brought up virgins.", "ylt": "Be ashamed, O Zidon; for the sea spake, The strength of the sea, saying: `I have not been pained, nor have I brought forth, Nor have I nourished young men, nor brought up virgins.'", "dra": "Be thou ashamed, O Sidon: for the sea speaketh, even the strength of the sea, saying: I have not been in labour, nor have I brought forth, nor have I nourished up young men, nor brought up virgins.", "bbe": "Be shamed, O Zidon: for the sea, the strong place of the sea has said, I have not been with child, or given birth; I have not taken care of young men, or kept watch over the growth of virgins.", "geneva": "Be ashamed, thou Zidon: for the sea hath spoken, euen the strength of the sea, saying, I haue not trauailed, nor brought forth children, neither nourished yong men, nor brought vp virgins.", "wycliffe": "Thou, Sidon, be aschamed, seide the see, the strengthe of the see, and seide, Y trauelide not of child, and Y childide not, and Y nurschide not yonge men, and Y brouyte not fulli virgyns to encreessyng.", "rotherham": "Turn thou pale, O Zidon, For spoken hath the sea, the fortress of the sea saying,—I have neither been in pangs nor given birth I have neither brought up young men nor promoted virgins.", "darby": "Be thou ashamed, Sidon, for the sea hath spoken, the strength of the sea, saying, I have not travailed nor brought forth, neither have I nourished young men [nor] brought up virgins.", "twenty": "", "jps": "Be thou ashamed, O Zidon; for the sea hath spoken, the stronghold of the sea, saying: 'I have not travailed, nor brought forth, neither have I reared young men, nor brought up virgins.'", "acv": "Be thou ashamed, O Sidon, for the sea has spoken, the stronghold of the sea, saying, I have not travailed, nor brought forth, neither have I nourished young men, nor brought up virgins.", "anderson": "", "haweis": "", "noyes": "Be thou ashamed, O Sidon, for the sea hath spoken, The fortress of the sea hath spoken thus: \"I have not travailed, nor brought forth children; I have not nourished youths, nor brought up virgins.\"", "webster": "Be thou ashamed, O Zidon: for the sea hath spoken, [even] the strength of the sea, saying, I travail not, nor bring forth children, neither do I nourish young men, [nor] bring up virgins.", "vulgate": "erubesce Sidon ait enim mare fortitudo maris dicens non parturivi et non peperi et non enutrivi iuvenes nec ad incrementum perduxi virgines;", "brenton": "Be ashamed, O Sidon: the sea has said, yea, the strength of the sea has said, I have not travailed, nor brought forth, nor have I brought up young men, nor reared virgins."}}, {"v": 5, "ref": "23:5", "o": "כַּֽ/אֲשֶׁר שֵׁ֖מַע לְ/מִצְרָ֑יִם יָחִ֖ילוּ כְּ/שֵׁ֥מַע צֹֽר", "en": {"kjv": "As at the report concerning Egypt, so shall they be sorely pained at the report of Tyre.", "web": "When the report comes to Egypt, they will be in anguish at the report of Tyre.", "bsb": "When the report reaches Egypt, they will writhe in agony over the news of Tyre.", "asv": "When the report cometh to Egypt, they shall be sorely pained at the report of Tyre.", "ylt": "As at the report of Egypt they are pained, So at the report of Tyre.", "dra": "When it shall be heard in Egypt, they will be sorry when they shall hear of Tyre:", "bbe": "When the news comes to Egypt they will be bitterly pained at the fate of Tyre.", "geneva": "When the fame commeth to the Egyptians, they shall be sorie, concerning the rumour of Tyrus.", "wycliffe": "Whanne it schal be herd in Egipt, thei schulen make sorewe, whanne thei heren of Tire.", "rotherham": "Like the report of Egypt, They shall be in pangs at the like report of Tyre.", "darby": "— When the report came into Egypt, they were sorely pained at the news of Tyre.", "twenty": "", "jps": "When the report cometh to Egypt, they shall be sorely pained at the report of Tyre.", "acv": "When the report comes to Egypt, they shall be greatly pained at the report of Tyre.", "anderson": "", "haweis": "", "noyes": "When the tidings shall reach Egypt, They shall be filled with anguish at the tidings concerning Tyre.", "webster": "As at the report concerning Egypt, [so] shall they be sorely pained at the report of Tyre.", "vulgate": "cum auditum fuerit in Aegypto dolebunt cum audierint de Tyro;", "brenton": "Moreover when it shall be heard in Egypt, sorrow shall seize them for Tyre."}}, {"v": 6, "ref": "23:6", "o": "עִבְר֖וּ תַּרְשִׁ֑ישָׁ/ה הֵילִ֖ילוּ יֹ֥שְׁבֵי אִֽי", "en": {"kjv": "Pass ye over to Tarshish; howl, ye inhabitants of the isle.", "web": "Pass over to Tarshish! Wail, you inhabitants of the coast!", "bsb": "Cross over to Tarshish; wail, O inhabitants of the coastland!", "asv": "Pass ye over to Tarshish; wail, ye inhabitants of the coast.", "ylt": "Pass over to Tarshish, howl, ye inhabitants of the isle,", "dra": "Pass over the seas, howl, ye inhabitants of the island.", "bbe": "Go over to Tarshish; give cries of sorrow, O men of the sea-land.", "geneva": "Goe you ouer to Tarshish: howle, yee that dwell in the yles.", "wycliffe": "Passe ye the sees; yelle ye, that dwellen in the ile.", "rotherham": "Pass ye over to Tarshish,—Howl ye inhabitants of the Coast:", "darby": "Pass over to Tarshish; howl, ye inhabitants of the coast!", "twenty": "", "jps": "Pass ye over to Tarshish; howl, ye inhabitants of the coast-land.", "acv": "Pass ye over to Tarshish. Wail, ye inhabitants of the coast.", "anderson": "", "haweis": "", "noyes": "Pass ye over to Tarshish; Howl, ye inhabitants of the sea-coast!", "webster": "Pass ye over to Tarshish; howl, ye inhabitants of the isle.", "vulgate": "transite maria ululate qui habitatis in insula;", "brenton": "Depart ye to Carthage; howl, ye that dwell in this island."}}, {"v": 7, "ref": "23:7", "o": "הֲ/זֹ֥את לָ/כֶ֖ם עַלִּיזָ֑ה מִֽ/ימֵי קֶ֤דֶם קַדְמָתָ/הּ֙ יֹבִל֣וּ/הָ רַגְלֶ֔י/הָ מֵֽ/רָח֖וֹק לָ/גֽוּר", "en": {"kjv": "Is this your joyous city, whose antiquity is of ancient days? her own feet shall carry her afar off to sojourn.", "web": "Is this your joyous city, whose antiquity is of ancient days, whose feet carried her far away to travel?", "bsb": "Is this your jubilant city, whose origin is from antiquity, whose feet have taken her to settle far away?", "asv": "Is this your joyous city, whose antiquity is of ancient days, whose feet carried her afar off to sojourn?", "ylt": "Is this your exulting one? From the days of old is her antiquity, Carry her do her own feet afar off to sojourn.", "dra": "Is not this your city, which gloried from of old in her antiquity? her feet shall carry her afar off to sojourn.", "bbe": "Is this the town which was full of joy, whose start goes back to times long past, whose wanderings took her into far-off countries?", "geneva": "Is not this that your glorious citie? her antiquitie is of ancient daies: her owne feete shall leade her afarre off to be a soiourner.", "wycliffe": "Whether this citee is not youre, that hadde glorie fro elde daies in his eldnesse? the feet therof schulen lede it fer, to go in pilgrymage.", "rotherham": "Is this to you an exultation? Though from ancient days, is her antiquity, Yet shall her own feet carry her away, far off to dwell.", "darby": "Is this your joyous [city], whose antiquity is of ancient days? Her feet shall carry her afar off to sojourn.", "twenty": "", "jps": "Is this your joyous city, whose feet in antiquity, in ancient days, carried her afar off to sojourn?", "acv": "Is this your joyous city, whose antiquity is of ancient days, whose feet carried her afar off to sojourn?", "anderson": "", "haweis": "", "noyes": "Is this your joyous city, Whose antiquity is of ancient days? Now her own feet bear her To sojourn far away.", "webster": "[Is] this your joyous [city], whose antiquity [is] of ancient days? her own feet shall carry her far off to sojourn.", "vulgate": "numquid non haec vestra est quae gloriabatur a diebus pristinis in antiquitate sua ducent eam pedes sui longe ad peregrinandum;", "brenton": "Was not this your pride from the beginning, before she was given up?"}}, {"v": 8, "ref": "23:8", "o": "מִ֚י יָעַ֣ץ זֹ֔את עַל צֹ֖ר הַ/מַּֽעֲטִירָ֑ה אֲשֶׁ֤ר סֹחֲרֶ֨י/ה֙ שָׂרִ֔ים כִּנְעָנֶ֖י/הָ נִכְבַּדֵּי אָֽרֶץ", "en": {"kjv": "Who hath taken this counsel against Tyre, the crowning city, whose merchants are princes, whose traffickers are the honourable of the earth?", "web": "Who has planned this against Tyre, the giver of crowns, whose merchants are princes, whose traffickers are the honorable of the earth?", "bsb": "Who planned this against Tyre, the bestower of crowns, whose traders are princes, whose merchants are renowned on the earth?", "asv": "Who hath purposed this against Tyre, the bestower of crowns, whose merchants are princes, whose traffickers are the honorable of the earth?", "ylt": "Who hath counselled this against Tyre, The crowning one, whose traders are princes, Her merchants the honoured of earth?'", "dra": "Who hath taken this counsel against Tyre, that was formerly crowned, whose merchants were princes, and her traders the nobles of the earth?", "bbe": "By whom was this purposed against Tyre, the crowning town, whose traders are chiefs, whose business men are honoured in the land?", "geneva": "Who hath decreed this against Tyrus (that crowneth men) whose marchantes are princes? whose chapmen are the nobles of the worlde?", "wycliffe": "Who thouyte this thing on Tire sum tyme crownede, whos marchauntis weren princes, the selleris of marchaundie therof weren noble men of erthe?", "rotherham": "Who hath purposed this, against Tyre, The bestower of crowns,—Whose merchants are princes, Her traders the honourable of the earth?", "darby": "Who hath purposed this against Tyre, the distributor of crowns, whose merchants were princes, whose dealers were the honourable of the earth?", "twenty": "", "jps": "Who hath devised this against Tyre, the crowning city, whose merchants are princes, whose traffickers are the honourable of the earth?", "acv": "Who has purposed this against Tyre, the bestower of crowns, whose merchants are rulers, whose traders are the honored of the earth?", "anderson": "", "haweis": "", "noyes": "Who hath purposed this against Tyre, The dispenser of crowns, Whose merchants are princes, Whose traders the nobles of the earth?", "webster": "Who hath taken this counsel against Tyre, the crowning [city], whose merchants [are] princes, whose traders [are] the honorable of the earth?", "vulgate": "quis cogitavit hoc super Tyrum quondam coronatam cuius negotiatores principes institores eius incliti terrae;", "brenton": "Who has devised this counsel against Tyre? Is she inferior? or has she no strength? her merchants were the glorious princes of the earth."}}, {"v": 9, "ref": "23:9", "o": "יְהוָ֥ה צְבָא֖וֹת יְעָצָ֑/הּ לְ/חַלֵּל֙ גְּא֣וֹן כָּל צְבִ֔י לְ/הָקֵ֖ל כָּל נִכְבַּדֵּי אָֽרֶץ", "en": {"kjv": "The Lord of hosts hath purposed it, to stain the pride of all glory, and to bring into contempt all the honourable of the earth.", "web": "Yahweh of Armies has planned it, to stain the pride of all glory, to bring into contempt all the honorable of the earth.", "bsb": "The LORD of Hosts planned it, to defile all its glorious beauty, to disgrace all the renowned of the earth.", "asv": "Jehovah of hosts hath purposed it, to stain the pride of all glory, to bring into contempt all the honorable of the earth.", "ylt": "Jehovah of Hosts hath counselled it, To pollute the excellency of all beauty, To make light all the honoured of earth.", "dra": "The Lord of hosts hath designed it, to pull down the pride of all glory, and bring to disgrace all the glorious ones of the earth.", "bbe": "It was the purpose of the Lord of armies to put pride to shame, to make sport of the glory of those who are honoured in the earth.", "geneva": "The Lord of hostes hath decreed this, to staine the pride of all glorie, and to bring to contempt all them that be glorious in the earth.", "wycliffe": "The Lord of oostis thouyte this thing, that he schulde drawe doun the pride of al glorie, and that he schulde bringe to schenschipe alle the noble men of erthe.", "rotherham": "Yahweh of hosts, hath purposed it,—To humble the pride of all beauty, To make of little esteem all the honourable of the earth.", "darby": "Jehovah of hosts hath purposed it, to profane the pride of all glory, to bring to nought all the honourable of the earth.", "twenty": "", "jps": "HaShem of hosts hath devised it, to pollute the pride of all glory, to bring into contempt all the honourable of the earth.", "acv": "Jehovah of hosts has purposed it, to stain the pride of all glory, to bring into contempt all the honorable of the earth.", "anderson": "", "haweis": "", "noyes": "Jehovah of hosts hath purposed it, To bring down the pride of all glory, To humble the nobles of the earth.", "webster": "The LORD of hosts hath purposed it, to stain the pride of all glory, [and] to bring into contempt all the honorable of the earth.", "vulgate": "Dominus exercituum cogitavit hoc ut detraheret superbiam omnis gloriae et ad ignominiam deduceret universos inclitos terrae;", "brenton": "The Lord of hosts has purposed to bring down all the pride of the glorious ones, and to disgrace every glorious thing on the earth."}}, {"v": 10, "ref": "23:10", "o": "עִבְרִ֥י אַרְצֵ֖/ךְ כַּ/יְאֹ֑ר בַּת תַּרְשִׁ֕ישׁ אֵ֖ין מֵ֥זַח עֽוֹד", "en": {"kjv": "Pass through thy land as a river, O daughter of Tarshish: there is no more strength.", "web": "Pass through your land like the Nile, daughter of Tarshish. There is no restraint any more.", "bsb": "Cultivate your land like the Nile, O Daughter of Tarshish; there is no longer a harbor.", "asv": "Pass through thy land as the Nile, O daughter of Tarshish; there is no restraint any more.", "ylt": "Pass through thy land as a brook, Daughter of Tarshish, there is no more a girdle.", "dra": "Pass thy land as a river, O daughter of the sea, thou hast a girdle no more.", "bbe": "Let your land be worked with the plough, O daughter of Tarshish; there is no longer any harbour.", "geneva": "Passe through thy lande like a flood to the daughter of Tarshish: there is no more strength.", "wycliffe": "Thou douyter of the see, passe thi lond as a flood; a girdil is no more to thee.", "rotherham": "Pass through thy land as the Nile,—O daughter of Tarshish, there is no restraint any longer!", "darby": "Overflow thy land like the Nile, daughter of Tarshish: there is no more restraint.", "twenty": "", "jps": "Overflow thy land as the Nile, O daughter of Tarshish! there is no girdle any more.", "acv": "Pass through thy land as the Nile, O daughter of Tarshish, there is no restraint any more.", "anderson": "", "haweis": "", "noyes": "Go over thy land like the Nile, O daughter of Tarshish! Now thy bonds are broken.", "webster": "Pass through thy land as a river, O daughter of Tarshish: [there is] no more strength.", "vulgate": "transi terram tuam quasi flumen filia maris non est cingulum ultra tibi;", "brenton": "Till thy land; for ships no more come out of Carthage."}}, {"v": 11, "ref": "23:11", "o": "יָד/וֹ֙ נָטָ֣ה עַל הַ/יָּ֔ם הִרְגִּ֖יז מַמְלָכ֑וֹת יְהוָה֙ צִוָּ֣ה אֶל כְּנַ֔עַן לַ/שְׁמִ֖ד מָעֻזְנֶֽי/הָ", "en": {"kjv": "He stretched out his hand over the sea, he shook the kingdoms: the Lord hath given a commandment against the merchant city, to destroy the strong holds thereof.", "web": "He has stretched out his hand over the sea. He has shaken the kingdoms. Yahweh has ordered the destruction of Canaan’s strongholds.", "bsb": "The LORD has stretched out His hand over the sea; He has made kingdoms tremble. He has given a command that the strongholds of Canaan be destroyed.", "asv": "He hath stretched out his hand over the sea, he hath shaken the kingdoms: Jehovah hath given commandment concerning Canaan, to destroy the strongholds thereof.", "ylt": "His hand He hath stretched out over the sea, He hath caused kingdoms to tremble, Jehovah hath charged concerning the merchant one, To destroy her strong places.", "dra": "He stretched out his hand over the sea, he troubled kingdoms: the Lord hath given a charge against Chanaan, to destroy the strong ones thereof.", "bbe": "His hand is stretched out over the sea, the kingdoms are shaking: the Lord has given orders about Canaan, to make waste its strong places.", "geneva": "He stretched out his hand vpon the sea: he shooke the kingdomes: the Lord hath giuen a commandement concerning the place of marchandise, to destroy the power thereof.", "wycliffe": "It stretchide forth his hond aboue the see, and disturblide rewmes. The Lord sente ayenes Canaan, for to al to-breke the stronge men therof;", "rotherham": "His hand, hath he stretched out over the sea, He hath shaken kingdoms,—Yahweh, hath given command against the Phoenician coast, To destroy her fortresses.", "darby": "He hath stretched out his hand over the sea, he shaketh the kingdoms. Jehovah hath given a commandment concerning Canaan, to destroy the strongholds thereof,", "twenty": "", "jps": "He hath stretched out His hand over the sea, He hath shaken the kingdoms; HaShem hath given commandment concerning Canaan, to destroy the strongholds thereof;", "acv": "He has stretched out his hand over the sea. He has shaken the kingdoms. Jehovah has given commandment concerning Canaan, to destroy the strongholds of it.", "anderson": "", "haweis": "", "noyes": "He hath stretched out his hand over the sea, He hath made the kingdoms tremble; Jehovah hath given commandment concerning Canaan To destroy her strong holds.", "webster": "He stretched his hand over the sea, he shook the kingdoms: the LORD hath given a commandment against the merchant [city], to destroy its strong holds.", "vulgate": "manum suam extendit super mare conturbavit regna Dominus mandavit adversum Chanaan ut contereret fortes eius;", "brenton": "And thy hand prevails no more by sea, which troubled kings: the Lord of hosts has given a command concerning Chanaan, to destroy the strength thereof."}}, {"v": 12, "ref": "23:12", "o": "וַ/יֹּ֕אמֶר לֹֽא תוֹסִ֥יפִי ע֖וֹד לַ/עְל֑וֹז הַֽ/מְעֻשָּׁקָ֞ה בְּתוּלַ֣ת בַּת צִיד֗וֹן כתיים כִּתִּים֙ ק֣וּמִי עֲבֹ֔רִי גַּם שָׁ֖ם לֹא יָנ֥וּחַֽ לָֽ/ךְ", "en": {"kjv": "And he said, Thou shalt no more rejoice, O thou oppressed virgin, daughter of Zidon: arise, pass over to Chittim; there also shalt thou have no rest.", "web": "He said, “You shall rejoice no more, you oppressed virgin daughter of Sidon. Arise, pass over to Kittim. Even there you will have no rest.”", "bsb": "He said, “You shall rejoice no more, O oppressed Virgin Daughter of Sidon. Get up and cross over to Cyprus— even there you will find no rest.”", "asv": "And he said, Thou shalt no more rejoice, O thou oppressed virgin daughter of Sidon: arise, pass over to Kittim; even there shalt thou have no rest.", "ylt": "And He saith, `Thou dost not add any more to exult, O oppressed one, virgin daughter of Zidon, To Chittim arise, pass over, Even there--there is no rest for thee.'", "dra": "And he said: Thou shalt glory no more, O virgin daughter of Sidon, who art oppressed: arise and sail over to Cethim, there also thou shalt have no rest.", "bbe": "And he said, There is no more joy for you, O crushed virgin daughter of Zidon: up! go over to Kittim; even there you will have no rest.", "geneva": "And he saide, Thou shalt no more reioyce when thou art oppressed: O virgin daughter of Zidon: rise vp, goe ouer vnto Chittim: yet there thou shalt haue no rest.", "wycliffe": "and he seide, Thou maide, the douyter of Sidon, that suffrist caleng, schalt no more adde, that thou haue glorie. Rise thou, and passe ouer the see in to Sechym; there also no reste schal be to thee.", "rotherham": "Therefore hath he said,—No more, again, do thou exult, Thou violated virgin daughter of Zidon,—To Cyprus, arise and pass over, Even there, shall one find thee no rest.", "darby": "and hath said, Thou shalt no more exult, [thou] oppressed virgin, daughter of Sidon: get thee up, pass over to Chittim; even there shalt thou have no rest.", "twenty": "", "jps": "And He said: 'Thou shalt no more rejoice.' O thou oppressed virgin daughter of Zidon, arise, pass over to Kittim; even there shalt thou have no rest.", "acv": "And he said, Thou shall no more rejoice, O thou oppressed virgin daughter of Sidon. Arise, pass over to Kittim, even there shall thou have no rest.", "anderson": "", "haweis": "", "noyes": "He hath said, Thou shalt no more rejoice, Thou ravished virgin, daughter of Sidon! Arise, pass over to the Chittaeans; Yet even there shalt thou have no rest.", "webster": "And he said, Thou shalt no more rejoice, O thou oppressed virgin, daughter of Zidon: arise, pass over to Chittim; there also shalt thou have no rest.", "vulgate": "et dixit non adicies ultra ut glorieris calumniam sustinens virgo filia Sidonis in Cetthim consurgens transfreta ibi quoque non erit requies tibi;", "brenton": "And men shall say, Ye shall no longer at all continue to insult and injure the daughter of Sidon: and if thou depart to the Citians, neither there shalt thou have rest."}}, {"v": 13, "ref": "23:13", "o": "הֵ֣ן אֶ֣רֶץ כַּשְׂדִּ֗ים זֶ֤ה הָ/עָם֙ לֹ֣א הָיָ֔ה אַשּׁ֖וּר יְסָדָ֣/הּ לְ/צִיִּ֑ים הֵקִ֣ימוּ בחיני/ו בַחוּנָ֗י/ו עֹרְרוּ֙ אַרְמְנוֹתֶ֔י/הָ שָׂמָ֖/הּ לְ/מַפֵּלָֽה", "en": {"kjv": "Behold the land of the Chaldeans; this people was not, till the Assyrian founded it for them that dwell in the wilderness: they set up the towers thereof, they raised up the palaces thereof; and he brought it to ruin.", "web": "Behold, the land of the Chaldeans. This people was not. The Assyrians founded it for those who dwell in the wilderness. They set up their towers. They overthrew its palaces. They made it a ruin.", "bsb": "Look at the land of the Chaldeans— a people now of no account. The Assyrians destined it for the desert creatures; they set up their siege towers and stripped its palaces. They brought it to ruin.", "asv": "Behold, the land of the Chaldeans: this people was not; the Assyrian founded it for them that dwell in the wilderness; they set up their towers; they overthrew the palaces thereof; they made it a ruin.", "ylt": "Lo, the land of the Chaldeans--this people was not, Asshur founded it for the Ziim, They raised its watch-towers, They lifted up her palaces, --He hath appointed her for a ruin!", "dra": "Behold the land of the Chaldeans, there was not such a people, the Assyrians founded it: they have led away the strong ones thereof into captivity, they have destroyed the houses thereof, they have, brought it to ruin.", "bbe": "...", "geneva": "Behold the lande of the Caldeans: this was no people: Asshur founded it by the inhabitantes of the wildernesse: they set vp the towers thereof: they raised the palaces thereof and hee brought it to ruine.", "wycliffe": "Lo! the lond of Caldeis, sich a puple was not; Assur foundide that Tyre; thei ledden ouer in to caitifte the strong men therof; thei myneden the housis therof, thei settiden it in to fallyng.", "rotherham": "Lo! the land of the Chaldeans, This is the people that was not, Assyria, founded it for the inhabitants of the desert,—They set up its siege-towers, They demolished its palaces Made it a ruin!", "darby": "Behold the land of the Chaldeans: this people did not exist; the Assyrian founded it for the dwellers in the desert: they set up their towers, they destroyed the palaces thereof; he brought it to ruin.", "twenty": "", "jps": "Behold, the land of the Chaldeans--this is the people that was not, when Asshur founded it for shipmen--they set up their towers, they overthrew the palaces thereof; it is made a ruin.", "acv": "Behold, the land of the Chaldeans. This people once was not. The Assyrian founded it for those who dwell in the wilderness. They set up their towers. They raised up the palaces of it. Then they made it a ruin.", "anderson": "", "haweis": "", "noyes": "Behold the land of the Chaldaeans, Who, not long ago, were not a people,—The Assyrian assigned it to the inhabitants of the wilderness,—They raise their watch-towers; They destroy her palaces; They make her a heap of ruins.", "webster": "Behold the land of the Chaldeans; this people was not, [till] the Assyrian founded it for them that dwell in the wilderness: they set up its towers, they raised up its palaces; [and] he brought it to ruin.", "vulgate": "ecce terra Chaldeorum talis populus non fuit Assur fundavit eam in captivitatem transduxerunt robustos eius suffoderunt domos eius posuerunt eam in ruinam;", "brenton": "And if thou depart to the land of the Chaldeans, this also is laid waste by the Assyrians, for her wall is fallen."}}, {"v": 14, "ref": "23:14", "o": "הֵילִ֖ילוּ אֳנִיּ֣וֹת תַּרְשִׁ֑ישׁ כִּ֥י שֻׁדַּ֖ד מָעֻזְּ/כֶֽן", "en": {"kjv": "Howl, ye ships of Tarshish: for your strength is laid waste.", "web": "Howl, you ships of Tarshish, for your stronghold is laid waste!", "bsb": "Wail, O ships of Tarshish, for your harbor has been destroyed!", "asv": "Howl, ye ships of Tarshish; for your stronghold is laid waste.", "ylt": "Howl, ye ships of Tarshish, For your strength hath been destroyed.", "dra": "Howl, O ye ships of the sea, for your strength is laid waste.", "bbe": "Let a cry of sorrow go up, O ships of Tarshish: because your strong place is made waste.", "geneva": "Howle yee shippes of Tarshish, for your strength is destroyed.", "wycliffe": "Yelle, ye schippis of the see, for youre strengthe is distried.", "rotherham": "Howl, ye ships of Tarshish,—For laid waste is your fortress.", "darby": "Howl, ships of Tarshish! for your fortress is laid waste.", "twenty": "", "jps": "Howl, ye ships of Tarshish, for your stronghold is laid waste.", "acv": "Howl, ye ships of Tarshish, for your stronghold is laid waste.", "anderson": "", "haweis": "", "noyes": "Howl, ye ships of Tarshish! For your stronghold is destroyed.", "webster": "Howl, ye ships of Tarshish: for your strength is laid waste.", "vulgate": "ululate naves maris quia devastata est fortitudo vestra;", "brenton": "Howl, ye ships of Carthage: for your strong hold is destroyed."}}, {"v": 15, "ref": "23:15", "o": "וְ/הָיָה֙ בַּ/יּ֣וֹם הַ/ה֔וּא וְ/נִשְׁכַּ֤חַת צֹר֙ שִׁבְעִ֣ים שָׁנָ֔ה כִּ/ימֵ֖י מֶ֣לֶךְ אֶחָ֑ד מִ/קֵּ֞ץ שִׁבְעִ֤ים שָׁנָה֙ יִהְיֶ֣ה לְ/צֹ֔ר כְּ/שִׁירַ֖ת הַ/זּוֹנָֽה", "en": {"kjv": "And it shall come to pass in that day, that Tyre shall be forgotten seventy years, according to the days of one king: after the end of seventy years shall Tyre sing as an harlot.", "web": "It will come to pass in that day that Tyre will be forgotten seventy years, according to the days of one king. After the end of seventy years it will be to Tyre like in the song of the prostitute.", "bsb": "At that time Tyre will be forgotten for seventy years—the span of a king’s life. But at the end of seventy years, it will happen to Tyre as in the song of the harlot:", "asv": "And it shall come to pass in that day, that Tyre shall be forgotten seventy years, according to the days of one king: after the end of seventy years it shall be unto Tyre as in the song of the harlot.", "ylt": "And it hath come to pass, in that day, That forgotten is Tyre seventy years, According to the days of one king. At the end of seventy years there is to Tyre as the song of the harlot.", "dra": "And it shall come to pass in that day that thou, O Tyre, shalt be forgotten, seventy years, according to the days of one king: but after seventy years, there shall be unto Tyre as the song of a harlot.", "bbe": "And it will be in that day that Tyre will go out of mind for seventy years, that is, the days of one king: after the end of seventy years it will be for Tyre as in the song of the loose woman.", "geneva": "And in that day shall Tyrus bee forgotten seuentie yeeres, (according to the yeeres of one King) at the ende of seuentie yeeres shall Tyrus sing as an harlot.", "wycliffe": "And it schal be, in that dai, thou Tire, schalt be in foryetyng bi seuenti yeer, as the daies of o king; but aftir seuenti yeer, as the song of an hoore schal be to Tyre.", "rotherham": "So shall it be in that day, That Tyre shall be forgotten seventy years, According to the days of a certain king: At the end of seventy years, shall it befall Tyre according to the song of the harlot:", "darby": "And it shall come to pass in that day, that Tyre shall be forgotten seventy years, according to the days of one king. At the end of seventy years it shall be for Tyre as the harlot's song.", "twenty": "", "jps": "And it shall come to pass in that day, that Tyre shall be forgotten seventy years, according to the days of one king; after the end of seventy years it shall fare with Tyre as in the song of the harlot:", "acv": "And it shall come to pass in that day, that Tyre shall be forgotten seventy years, according to the days of one king. After the end of seventy years it shall be to Tyre as in the song of the harlot:", "anderson": "", "haweis": "", "noyes": "And it shall come to pass in that day, That Tyre shall be forgotten seventy years, According to the days of one king; But at the end of seventy years It shall be with Tyre as in the song of the harlot:", "webster": "And it shall come to pass in that day, that Tyre shall be forgotten seventy years, according to the days of one king: after the end of seventy years shall Tyre sing as a harlot.", "vulgate": "et erit in die illa in oblivione eris o Tyre septuaginta annis sicut dies regis unius post septuaginta autem annos erit Tyro quasi canticum meretricis;", "brenton": "And it shall come to pass in that day, that Tyre shall be left seventy years, as the time of a king, as the time of a man: and it shall come to pass after seventy years, that Tyre shall be as the song of a harlot."}}, {"v": 16, "ref": "23:16", "o": "קְחִ֥י כִנּ֛וֹר סֹ֥בִּי עִ֖יר זוֹנָ֣ה נִשְׁכָּחָ֑ה הֵיטִ֤יבִי נַגֵּן֙ הַרְבִּי שִׁ֔יר לְמַ֖עַן תִּזָּכֵֽרִי", "en": {"kjv": "Take an harp, go about the city, thou harlot that hast been forgotten; make sweet melody, sing many songs, that thou mayest be remembered.", "web": "Take a harp; go about the city, you prostitute that has been forgotten. Make sweet melody. Sing many songs, that you may be remembered.", "bsb": "“Take up your harp, stroll through the city, O forgotten harlot. Make sweet melody, sing many a song, so you will be remembered.”", "asv": "Take a harp, go about the city, thou harlot that hast been forgotten; make sweet melody, sing many songs, that thou mayest be remembered.", "ylt": "Take a harp, go round the city, O forgotten harlot, play well, Multiply song that thou mayest be remembered.", "dra": "Take a harp, go about the city, harlot that hast been forgotten: sing well, sing many a song, that thou mayst be remembered.", "bbe": "Take an instrument of music, go about the town, O loose woman who has gone out from the memory of man; make sweet melody with songs, so that you may come back to men's minds.", "geneva": "Take an harpe and go about the citie: (thou harlot thou hast beene forgotten) make sweete melodie, sing moe songes that thou maiest be remembred.", "wycliffe": "Thou hoore, youun to foryetyng, take an harpe, cumpasse the citee; synge thou wel, vse thou ofte a song, that mynde be of thee.", "rotherham": "Take thou a lyre, Go round the city, O harlot forgotten,—Sweetly touch the strings Lengthen out the song, That thou mayest be called to mind.", "darby": "Take a harp, go about the city, thou forgotten harlot! Make sweet melody, sing many songs, that thou mayest be remembered.", "twenty": "", "jps": "Take a harp, go about the city, thou harlot long forgotten; make sweet melody, sing many songs, that thou mayest be remembered.", "acv": "Take a harp, go about the city, thou harlot who has been forgotten. Make sweet melody, sing many songs, that thou may be remembered.", "anderson": "", "haweis": "", "noyes": "\"Take thy lyre, go about the city, O harlot, long forgotten; Make sweet melody; sing many songs, That thou mayst again be remembered!\"", "webster": "Take a harp, go about the city, thou harlot that hast been forgotten; make sweet melody, sing many songs, that thou mayest be remembered.", "vulgate": "sume citharam circui civitatem meretrix oblivioni tradita bene cane frequenta canticum ut memoria tui sit;", "brenton": "Take a harp, go about, O city, thou harlot that hast been forgotten; play well on the harp, sing many songs, that thou mayest be remembered."}}, {"v": 17, "ref": "23:17", "o": "וְ/הָיָ֞ה מִ/קֵּ֣ץ שִׁבְעִ֣ים שָׁנָ֗ה יִפְקֹ֤ד יְהוָה֙ אֶת צֹ֔ר וְ/שָׁבָ֖ה לְ/אֶתְנַנָּ֑/ה וְ/זָֽנְתָ֛ה אֶת כָּל מַמְלְכ֥וֹת הָ/אָ֖רֶץ עַל פְּנֵ֥י הָ/אֲדָמָֽה", "en": {"kjv": "And it shall come to pass after the end of seventy years, that the Lord will visit Tyre, and she shall turn to her hire, and shall commit fornication with all the kingdoms of the world upon the face of the earth.", "web": "It will happen after the end of seventy years that Yahweh will visit Tyre, and she shall return to her wages, and will play the prostitute with all the kingdoms of the world on the surface of the earth.", "bsb": "And at the end of seventy years, the LORD will restore Tyre. Then she will return to hire as a prostitute and sell herself to all the kingdoms on the face of the earth.", "asv": "And it shall come to pass after the end of seventy years, that Jehovah will visit Tyre, and she shall return to her hire, and shall play the harlot with all the kingdoms of the world upon the face of the earth.", "ylt": "And it hath come to pass, At the end of seventy years Jehovah inspecteth Tyre, And she hath repented of her gift, That she committed fornication With all kingdoms of the earth on the face of the ground.", "dra": "And it shall come to pass after seventy years, that the Lord will visit Tyre, and will bring her back again to her traffic: and she shall commit fornication again with all the kingdoms of the world upon the face of the earth.", "bbe": "And it will be after the end of seventy years, that the Lord will have mercy on Tyre, and she will go back to her trade, acting as a loose woman with all the kingdoms of the world on the face of the earth.", "geneva": "And at the ende of seuentie yeres shall the Lord visite Tyrus, and shee shall returne to her wages, and shall commit fornication with all the kingdomes of the earth, that are in the world.", "wycliffe": "And it schal be, aftir seuenti yeer, the Lord schal visite Tire, and schal brynge it ayen to hise hiris; and eft it schal be, whanne it schal do fornycacioun with alle rewmes of erthe, on the face of erthe.", "rotherham": "So shall it be, at the end of seventy years, That Yahweh will visit Tyre, And she will return to her hire,—Yea she will play the harlot—with all the kingdoms of the earth, upon the face of the ground.", "darby": "And it shall come to pass at the end of seventy years, that Jehovah will visit Tyre; and she will return to her hire, and will commit fornication with all the kingdoms of the earth upon the face of the ground.", "twenty": "", "jps": "And it shall come to pass after the end of seventy years, that HaShem will remember Tyre, and she shall return to her hire, and shall have commerce with all the kingdoms of the world upon the face of the earth.", "acv": "And it came to pass after the end of seventy years, that Jehovah examined Tyre, and she has repented of her gift, that she play the harlot with all the kingdoms of the world upon the face of the earth.", "anderson": "", "haweis": "", "noyes": "At the end of seventy years shall Jehovah show regard to Tyre, And she shall return to her hire, And play the harlot with all the kingdoms of the world, That are upon the face of the earth.", "webster": "And it shall come to pass after the end of seventy years, that the LORD will visit Tyre, and she shall turn to her hire, and shall commit fornication with all the kingdoms of the world upon the face of the earth.", "vulgate": "et erit post septuaginta annos visitabit Dominus Tyrum et reducet eam ad mercedes suas et rursum fornicabitur cum universis regnis terrae super faciem terrae;", "brenton": "And it shall come to pass after the seventy years, that God will visit Tyre, and she shall be again restored to her primitive state, and she shall be a mart for all the kingdoms of the world on the face of the earth."}}, {"v": 18, "ref": "23:18", "o": "וְ/הָיָ֨ה סַחְרָ֜/הּ וְ/אֶתְנַנָּ֗/הּ קֹ֚דֶשׁ לַֽ/יהוָ֔ה לֹ֥א יֵֽאָצֵ֖ר וְ/לֹ֣א יֵֽחָסֵ֑ן כִּ֣י לַ/יֹּשְׁבִ֞ים לִ/פְנֵ֤י יְהוָה֙ יִֽהְיֶ֣ה סַחְרָ֔/הּ לֶ/אֱכֹ֥ל לְ/שָׂבְעָ֖ה וְ/לִ/מְכַסֶּ֥ה עָתִֽיק", "en": {"kjv": "And her merchandise and her hire shall be holiness to the Lord: it shall not be treasured nor laid up; for her merchandise shall be for them that dwell before the Lord, to eat sufficiently, and for durable clothing.", "web": "Her merchandise and her wages will be holiness to Yahweh. It will not be treasured nor laid up; for her merchandise will be for those who dwell before Yahweh, to eat sufficiently, and for durable clothing.", "bsb": "Yet her profits and wages will be set apart to the LORD; they will not be stored or saved, for her profit will go to those who live before the LORD, for abundant food and fine clothing.", "asv": "And her merchandise and her hire shall be holiness to Jehovah: it shall not be treasured nor laid up; for her merchandise shall be for them that dwell before Jehovah, to eat sufficiently, and for durable clothing.", "ylt": "And her merchandise and her gift have been holy to Jehovah, Not treasured up nor stored, For to those sitting before Jehovah is her merchandise, To eat to satiety, and for a lasting covering!", "dra": "And her merchandise and her hire shall be sanctified to the Lord: they shall not be kept in store, nor laid up: for her merchandise shall be for them that shall dwell before the Lord, that they may eat unto fulness, and be clothed for a continuance.", "bbe": "And her goods and her trade will be holy to the Lord: they will not be kept back or stored up; for her produce will be for those living in the Lord's land, to give them food for their needs, and fair clothing.", "geneva": "Yet her occupying and her wages shall bee holy vnto the Lord: it shall not be laied vp nor kept in store, but her marchandise shalbe for them that dwell before the Lord, to eate sufficiently, and to haue durable clothing.", "wycliffe": "And the marchaundies therof and the meedis therof schulen be halewid to the Lord; tho schulen not be hid, nethir schulen be leid vp; for whi the marchaundie therof schal be to hem that dwellen bifore the Lord, that thei ete to fulnesse, and be clothid `til to eldnesse.", "rotherham": "But her merchandise and her hire, shall be hallowed unto Yahweh, It shall not be stored up, nor hoarded,—For, to them who dwell before Yahweh, shall her merchandise belong, That they may eat to satisfaction And have stately apparel.", "darby": "And her merchandise and her hire shall be holy to Jehovah: it shall not be treasured nor laid up; for her merchandise shall be for them that dwell before Jehovah, to eat and be sufficed, and for excellent clothing.", "twenty": "", "jps": "And her gain and her hire shall be holiness to HaShem; it shall not be treasured nor laid up; for her gain shall be for them that dwell before HaShem, to eat their fill, and for stately clothing.", "acv": "And her merchandise and her pay shall be holiness to Jehovah. It shall not be treasured nor laid up, for her merchandise shall be for those who dwell before Jehovah, to eat sufficiently, and for durable clothing.", "anderson": "", "haweis": "", "noyes": "But her gain and her hire shall be holy to Jehovah; It shall not be treasured, nor laid up in store; But it shall be for them that dwell before Jehovah, For abundant food, and for splendid clothing.", "webster": "And her merchandise and her hire shall be holiness to the LORD: it shall not be treasured nor laid up; for her merchandise shall be for them that dwell before the LORD, for sufficient food, and for durable clothing.", "vulgate": "et erunt negotiatio eius et mercedes eius sanctificatae Domino non condentur neque reponentur quia his qui habitaverint coram Domino erit negotiatio eius ut manducent in saturitatem et vestiantur usque ad vetustatem;", "brenton": "And her trade and her gain shall be holiness to the Lord: it shall not be gathered for them, but for those that dwell before the Lord, even all her trade, to eat and drink and be filled, and for a covenant and a memorial before the Lord."}}]}, {"c": 24, "verses": [{"v": 1, "ref": "24:1", "o": "הִנֵּ֧ה יְהוָ֛ה בּוֹקֵ֥ק הָ/אָ֖רֶץ וּ/בֽוֹלְקָ֑/הּ וְ/עִוָּ֣ה פָנֶ֔י/הָ וְ/הֵפִ֖יץ יֹשְׁבֶֽי/הָ", "en": {"kjv": "Behold, the Lord maketh the earth empty, and maketh it waste, and turneth it upside down, and scattereth abroad the inhabitants thereof.", "web": "Behold, Yahweh makes the earth empty, makes it waste, turns it upside down, and scatters its inhabitants.", "bsb": "Behold, the LORD lays waste the earth and leaves it in ruins. He will twist its surface and scatter its inhabitants—", "asv": "Behold, Jehovah maketh the earth empty, and maketh it waste, and turneth it upside down, and scattereth abroad the inhabitants thereof.", "ylt": "Lo, Jehovah is emptying the land, And is making it waste, And hath overturned it on its face, And hath scattered its inhabitants.", "dra": "Behold the Lord shall lay waste the earth, and shall strip it, and shall afflict the face thereof, and scatter abroad the inhabitants thereof.", "bbe": "See, the Lord is making the earth waste and unpeopled, he is turning it upside down, and sending the people in all directions.", "geneva": "Behold, the Lord maketh the earth emptie, and hee maketh it waste: hee turneth it vpside downe, and scattereth abrode the inhabitants thereof.", "wycliffe": "Lo! the Lord schal distrie the erthe, and schal make it nakid, and schal turmente the face therof; and he schal scater abrood the dwelleris therof.", "rotherham": "Lo! Yahweh emptying the earth and laying it waste,—And he will overturn the face thereof, And scatter them who dwell therein.", "darby": "Behold, Jehovah maketh the land empty, and maketh it waste, and turneth it upside down, and scattereth abroad its inhabitants.", "twenty": "", "jps": "Behold, HaShem maketh the earth empty and maketh it waste, and turneth it upside down, and scattereth abroad the inhabitants thereof.", "acv": "Behold, Jehovah makes the earth empty, and makes it waste, and turns it upside down, and scatters abroad the inhabitants of it.", "anderson": "", "haweis": "", "noyes": "Behold, Jehovah emptieth and draineth the land; Yea, he turneth it upside down, and scattereth its inhabitants.", "webster": "Behold, the LORD maketh the earth empty, and maketh it waste, and turneth it upside down, and scattereth abroad its inhabitants.", "vulgate": "ecce Dominus dissipabit terram et nudabit eam et adfliget faciem eius et disperget habitatores eius;", "brenton": "Behold, the Lord is about to lay waste the world, and will make it desolate, and will lay bare the surface of it, and scatter them that dwell therein."}}, {"v": 2, "ref": "24:2", "o": "וְ/הָיָ֤ה כָ/עָם֙ כַּ/כֹּהֵ֔ן כַּ/עֶ֨בֶד֙ כַּֽ/אדֹנָ֔י/ו כַּ/שִּׁפְחָ֖ה כַּ/גְּבִרְתָּ֑/הּ כַּ/קּוֹנֶה֙ כַּ/מּוֹכֵ֔ר כַּ/מַּלְוֶה֙ כַּ/לֹּוֶ֔ה כַּ/נֹּשֶׁ֕ה כַּ/אֲשֶׁ֖ר נֹשֶׁ֥א בֽ/וֹ", "en": {"kjv": "And it shall be, as with the people, so with the priest; as with the servant, so with his master; as with the maid, so with her mistress; as with the buyer, so with the seller; as with the lender, so with the borrower; as with the taker of usury, so with the giver of usury to him.", "web": "It will be as with the people, so with the priest; as with the servant, so with his master; as with the maid, so with her mistress; as with the buyer, so with the seller; as with the creditor, so with the debtor; as with the taker of interest, so with the giver of interest.", "bsb": "people and priest alike, servant and master, maid and mistress, buyer and seller, lender and borrower, creditor and debtor.", "asv": "And it shall be, as with the people, so with the priest; as with the servant, so with his master; as with the maid, so with her mistress; as with the buyer, so with the seller; as with the creditor, so with the debtor; as with the taker of interest, so with the giver of interest to him.", "ylt": "And it hath been--as a people so a priest, As the servant so his master, As the maid-servant so her mistress, As the buyer so the seller, As the lender so the borrower, As the usurer so he who is lifting it on himself.", "dra": "And it shall be as with the people, so with the priest: and as with the servant so with his master: as with the handmaid, so with her mistress: as with the buyer, so with the seller: as with the lender, so with the borrower: as with him that calleth for his money, so with him that oweth.", "bbe": "And it will be the same for the people as for the priest; for the servant as for his master; and for the woman-servant as for her owner; the same for the one offering goods for a price as for him who takes them; the same for him who gives money at interest and for him who takes it; the same for him who lets others have the use of his property as for those who make use of it.", "geneva": "And there shalbe like people, like Priest, and like seruaunt, like master, like maide, like mistresse, like bier, like seller, like lender, like borower, like giuer, like taker to vsurie.", "wycliffe": "And it schal be, as the puple, so the preest; as the seruaunt, so his lord; as the handmaide, so the ladi of hir; as a biere, so he that sillith; as the leenere, so he that takith borewyng; as he that axith ayen, so he that owith.", "rotherham": "And it shall be—As the people, so, the priest, As the servant, so his lord, As the maid, so, her mistress,—As the buyer, so, the seller, As the lender, so, the borrower, As the debtor, so! his creditor.", "darby": "And it shall be, as with the people, so with the priest; as with the servant, so with his master; as with the maid, so with her mistress; as with the buyer, so with the seller; as with the lender, so with the borrower; as with the taker of usury, so with him from whom usury is taken.", "twenty": "", "jps": "And it shall be, as with the people, so with the priest; as with the servant, so with his master; as with the maid, so with her mistress; as with the buyer, so with the seller; as with the lender, so with the borrower; as with the creditor, so with the debtor.", "acv": "And it shall be, as with the people, so with the priest, as with the servant, so with his master, as with the maid, so with her mistress, as with the buyer, so with the seller, as with the creditor, so with the debtor, as with the taker of interest, so with the giver of interest to him.", "anderson": "", "haweis": "", "noyes": "As with the people, so is it with the priest; As with the servant, so with the master; As with the maid, so with the mistress; As with the buyer, so with the seller; As with the borrower, so with the lender; As with the usurer, so with the giver of usury.", "webster": "And it shall be, as with the people, so with the priest; as with the servant, so with his master; as with the maid, so with her mistress; as with the buyer, so with the seller; as with the lender, so with the borrower; as with the taker of interest, so with the giver of interest to him.", "vulgate": "et erit sicut populus sic sacerdos et sicut servus sic dominus eius sicut ancilla sic domina eius sicut emens sic ille qui vendit sicut fenerator sic is qui mutuum accipit sicut qui repetit sic qui debet;", "brenton": "And the people shall be as the priest, and the servant as the lord, and the maid as the mistress; the buyer shall be as the seller, the lender as the borrower, and the debtor as his creditor."}}, {"v": 3, "ref": "24:3", "o": "הִבּ֧וֹק תִּבּ֛וֹק הָ/אָ֖רֶץ וְ/הִבּ֣וֹז תִּבּ֑וֹז כִּ֣י יְהוָ֔ה דִּבֶּ֖ר אֶת הַ/דָּבָ֥ר הַ/זֶּֽה", "en": {"kjv": "The land shall be utterly emptied, and utterly spoiled: for the Lord hath spoken this word.", "web": "The earth will be utterly emptied and utterly laid waste; for Yahweh has spoken this word.", "bsb": "The earth will be utterly laid waste and thoroughly plundered. For the LORD has spoken this word.", "asv": "The earth shall be utterly emptied, and utterly laid waste; for Jehovah hath spoken this word.", "ylt": "Utterly emptied is the land, and utterly spoiled, For Jehovah hath spoken this word:", "dra": "With desolation shall the earth be laid waste, and it shall be utterly spoiled: for the Lord hath spoken this word.", "bbe": "The earth will be completely waste and without men; for this is the word of the Lord.", "geneva": "The earth shalbe cleane emptied, and vtterly spoiled: for the Lord hath spoken this worde.", "wycliffe": "Bi distriyng the lond schal be distried, and schal be maad nakid by rauyschyng; for whi the Lord spak this word.", "rotherham": "Emptied—emptied—shall be the earth yea pillaged—pillaged,—For, Yahweh, hath spoken this word.", "darby": "The land shall be utterly emptied, and utterly spoiled; for Jehovah hath spoken this word.", "twenty": "", "jps": "The earth shall be utterly emptied, and clean despoiled; for HaShem hath spoken this word.", "acv": "The earth shall be utterly emptied, and utterly laid waste, for Jehovah has spoken this word.", "anderson": "", "haweis": "", "noyes": "The land is utterly emptied and utterly plundered; For Jehovah hath spoken this word.", "webster": "The land shall be utterly emptied, and utterly spoiled: for the LORD hath spoken this word.", "vulgate": "dissipatione dissipabitur terra et direptione praedabitur Dominus enim locutus est verbum hoc;", "brenton": "The earth shall be completely laid waste, and the earth shall be utterly spoiled: for the mouth of the Lord has spoken these things."}}, {"v": 4, "ref": "24:4", "o": "אָבְלָ֤ה נָֽבְלָה֙ הָ/אָ֔רֶץ אֻמְלְלָ֥ה נָבְלָ֖ה תֵּבֵ֑ל אֻמְלָ֖לוּ מְר֥וֹם עַם הָ/אָֽרֶץ", "en": {"kjv": "The earth mourneth and fadeth away, the world languisheth and fadeth away, the haughty people of the earth do languish.", "web": "The earth mourns and fades away. The world languishes and fades away. The lofty people of the earth languish.", "bsb": "The earth mourns and withers; the world languishes and fades; the exalted of the earth waste away.", "asv": "The earth mourneth and fadeth away, the world languisheth and fadeth away, the lofty people of the earth do languish.", "ylt": "Mourned, faded hath the land, Languished, faded hath the world, Languished have they--the high place of the people of the land.", "dra": "The earth mourned, and faded away, and is weakened: the world faded away, the height of the people of the earth is weakened.", "bbe": "The earth is sorrowing and wasting away, the world is full of grief and wasting away, the high ones of the earth come to nothing.", "geneva": "The earth lamenteth and fadeth away: the world is feeble and decaied: the proude people of the earth are weakened.", "wycliffe": "The erthe morenyde, and fleet awei, and is maad sijk; the world fleet awei, the hiynesse of the puple of erthe is maad sijk,", "rotherham": "Mourneth, fadeth, the earth Languisheth, fadeth, the world,—Languished have the lofty of the people of the earth.", "darby": "The land mourneth, it fadeth away; the world languisheth, it fadeth away: the haughty people of the land do languish.", "twenty": "", "jps": "The earth fainteth and fadeth away, the world faileth and fadeth away, the lofty people of the earth do fail.", "acv": "The earth mourns and fades away. The world languishes and fades away. The lofty people of the earth languish.", "anderson": "", "haweis": "", "noyes": "The land mourneth, and withereth; The world languisheth, and withereth; The nobles of the people of the land do languish.", "webster": "The earth mourneth [and] fadeth away, the world languisheth [and] fadeth away, the haughty people of the earth do languish.", "vulgate": "luxit et defluxit terra et infirmata est defluxit orbis infirmata est altitudo populi terrae;", "brenton": "The earth mourns, and the world is ruined, the lofty ones of the earth are mourning."}}, {"v": 5, "ref": "24:5", "o": "וְ/הָ/אָ֥רֶץ חָנְפָ֖ה תַּ֣חַת יֹשְׁבֶ֑י/הָ כִּֽי עָבְר֤וּ תוֹרֹת֙ חָ֣לְפוּ חֹ֔ק הֵפֵ֖רוּ בְּרִ֥ית עוֹלָֽם", "en": {"kjv": "The earth also is defiled under the inhabitants thereof; because they have transgressed the laws, changed the ordinance, broken the everlasting covenant.", "web": "The earth also is polluted under its inhabitants, because they have transgressed the laws, violated the statutes, and broken the everlasting covenant.", "bsb": "The earth is defiled by its people; they have transgressed the laws; they have overstepped the decrees and broken the everlasting covenant.", "asv": "The earth also is polluted under the inhabitants thereof; because they have transgressed the laws, violated the statutes, broken the everlasting covenant.", "ylt": "And the land hath been defiled under its inhabitants, Because they have transgressed laws, They have changed a statute, They have made void a covenant age-during.", "dra": "And the earth is infected by the inhabitants thereof: because they have transgressed the laws, they have changed the ordinance, they have broken the everlasting covenant.", "bbe": "The earth has been made unclean by those living in it; because the laws have not been kept by them, the orders have been changed, and the eternal agreement has been broken.", "geneva": "The earth also deceiueth, because of the inhabitantes thereof: for they transgressed the lawes: they changed the ordinances, and brake the euerlasting couenant.", "wycliffe": "and the erthe is slayn of hise dwelleris. For thei passiden lawis, chaungiden riyt, distrieden euerlastynge boond of pees.", "rotherham": "Yea the earth itself is profaned under them who dwell therein,—For they have Set aside laws, Gone beyond statute, Broken an age-abiding covenant.", "darby": "And the land is polluted under the inhabitants thereof; for they have violated the laws, changed the statute, broken the everlasting covenant.", "twenty": "", "jps": "The earth also is defiled under the inhabitants thereof; because they have transgressed the laws, violated the statute, broken the everlasting covenant.", "acv": "The earth also is polluted under the inhabitants of it, because they have transgressed the laws, violated the statutes, broken the everlasting covenant.", "anderson": "", "haweis": "", "noyes": "The land was polluted under its inhabitants, Because they transgressed the law, they violated the statutes, They broke the everlasting covenant.", "webster": "The earth also is defiled under its inhabitants; because they have transgressed the laws, changed the ordinance, broken the everlasting covenant.", "vulgate": "et terra interfecta est ab habitatoribus suis quia transgressi sunt leges mutaverunt ius dissipaverunt foedus sempiternum;", "brenton": "And she has sinned by reason of her inhabitants; because they have transgressed the law, and changed the ordinances, even the everlasting covenant."}}, {"v": 6, "ref": "24:6", "o": "עַל כֵּ֗ן אָלָה֙ אָ֣כְלָה אֶ֔רֶץ וַֽ/יֶּאְשְׁמ֖וּ יֹ֣שְׁבֵי בָ֑/הּ עַל כֵּ֗ן חָרוּ֙ יֹ֣שְׁבֵי אֶ֔רֶץ וְ/נִשְׁאַ֥ר אֱנ֖וֹשׁ מִזְעָֽר", "en": {"kjv": "Therefore hath the curse devoured the earth, and they that dwell therein are desolate: therefore the inhabitants of the earth are burned, and few men left.", "web": "Therefore the curse has devoured the earth, and those who dwell therein are found guilty. Therefore the inhabitants of the earth are burned, and few men left.", "bsb": "Therefore a curse has consumed the earth, and its inhabitants must bear the guilt; the earth’s dwellers have been burned, and only a few survive.", "asv": "Therefore hath the curse devoured the earth, and they that dwell therein are found guilty: therefore the inhabitants of the earth are burned, and few men left.", "ylt": "Therefore a curse hath consumed the land, And the inhabitants in it are become desolate, Therefore consumed have been inhabitants of the land, And few men have been left.", "dra": "Therefore shall a curse devour the earth, and the inhabitants thereof shall sin: and therefore they that dwell therein shall be mad, and few men shall be left.", "bbe": "For this cause the earth is given up to the curse, and those in it are judged as sinners: for this cause those living on the earth are burned up, and the rest are small in number.", "geneva": "Therefore hath the curse deuoured the earth, and the inhabitantes thereof are desolate. Wherefore the inhabitants of the land are burned vp, and fewe men are left.", "wycliffe": "For this thing cursyng schal deuoure the erthe, and the dwelleris therof schulen do synne; and therfor the louyeris therof schulen be woode, and fewe men schulen be left.", "rotherham": "For this cause, a curse, hath devoured the earth, And punished are the dwellers therein,—For this cause, are burned the inhabitants of the earth, And the men left remaining—are few.", "darby": "Therefore doth the curse devour the earth, and they that dwell therein are held guilty; therefore the inhabitants of the earth are consumed, and few men are left.", "twenty": "", "jps": "Therefore hath a curse devoured the earth, and they that dwell therein are found guilty; therefore the inhabitants of the earth waste away, and men are left few.", "acv": "Therefore the curse has devoured the earth, and those who dwell in it are found guilty. Therefore the inhabitants of the earth are burned, and few men left.", "anderson": "", "haweis": "", "noyes": "Therefore a curse devoured the land; Its inhabitants suffered for their guilt; Therefore are the inhabitants of the land consumed with heat, And few of the men are left.", "webster": "Therefore hath the curse devoured the earth, and they that dwell in it are desolate: therefore the inhabitants of the earth are burned, and few men left.", "vulgate": "propter hoc maledictio vorabit terram et peccabunt habitatores eius ideoque insanient cultores eius et relinquentur homines pauci;", "brenton": "Therefore a curse shall consume the earth, because the inhabitants thereof have sinned: therefore the dwellers in the earth shall be poor, and few men shall be left."}}, {"v": 7, "ref": "24:7", "o": "אָבַ֥ל תִּיר֖וֹשׁ אֻמְלְלָה גָ֑פֶן נֶאֶנְח֖וּ כָּל שִׂמְחֵי לֵֽב", "en": {"kjv": "The new wine mourneth, the vine languisheth, all the merryhearted do sigh.", "web": "The new wine mourns. The vine languishes. All the merry-hearted sigh.", "bsb": "The new wine dries up, the vine withers. All the merrymakers now groan.", "asv": "The new wine mourneth, the vine languisheth, all the merry-hearted do sigh.", "ylt": "Mourned hath the new wine, languished the vine, Sighed have all the joyful of heart.", "dra": "The vintage hath mourned, the vine hath languished away, all the merry have sighed.", "bbe": "The new wine is thin, the vine is feeble, and all the glad-hearted make sounds of grief.", "geneva": "The wine faileth, the vine hath no might: all that were of merie heart, doe mourne.", "wycliffe": "Vyndage morenyde, the vyne is sijk; alle men that weren glad in herte weiliden.", "rotherham": "Mourneth the new wine. Withereth the vine,—Sighing are all the merryhearted:", "darby": "The new wine mourneth, the vine languisheth, all that were merry-hearted do sigh;", "twenty": "", "jps": "The new wine faileth, the vine fadeth; all the merry-hearted do sigh.", "acv": "The new wine mourns. The vine languishes. All the merry-hearted do sigh.", "anderson": "", "haweis": "", "noyes": "The new wine mourneth; The vine languisheth; All that were of a joyful heart do sigh;", "webster": "The new wine mourneth, the vine languisheth, all the merry-hearted do sigh.", "vulgate": "luxit vindemia infirmata est vitis ingemuerunt omnes qui laetabantur corde;", "brenton": "The wine shall mourn, the vine shall mourn, all the merry-hearted shall sigh."}}, {"v": 8, "ref": "24:8", "o": "שָׁבַת֙ מְשׂ֣וֹשׂ תֻּפִּ֔ים חָדַ֖ל שְׁא֣וֹן עַלִּיזִ֑ים שָׁבַ֖ת מְשׂ֥וֹשׂ כִּנּֽוֹר", "en": {"kjv": "The mirth of tabrets ceaseth, the noise of them that rejoice endeth, the joy of the harp ceaseth.", "web": "The mirth of tambourines ceases. The sound of those who rejoice ends. The joy of the harp ceases.", "bsb": "The joyful tambourines have ceased; the noise of revelers has stopped; the joyful harp is silent.", "asv": "The mirth of tabrets ceaseth, the noise of them that rejoice endeth, the joy of the harp ceaseth.", "ylt": "Ceased hath the joy of tabrets, Ceased hath the noise of exulting ones, Ceased hath the joy of a harp.", "dra": "The mirth of timbrels hath ceased, the noise of them that rejoice is ended, the melody of the harp is silent.", "bbe": "The pleasing sound of all instruments of music has come to an end, and the voices of those who are glad.", "geneva": "The mirth of tabrets ceaseth: the noyse of them that reioyce, endeth: the ioye of the harpe ceaseth.", "wycliffe": "The ioie of tympans ceesside, the sowne of glad men restide; the swetnesse of harpe with song was stille.", "rotherham": "Ceased hath the mirth of timbrels, Ended is the noise of the uproarious,—Ceased hath the mirth of the lyre:", "darby": "the mirth of tambours ceaseth, the noise of them that rejoice endeth, the joy of the harp ceaseth.", "twenty": "", "jps": "The mirth of tabrets ceaseth, the noise of them that rejoice endeth, the joy of the harp ceaseth.", "acv": "The mirth of tambourine ceases. The noise of those who rejoice ends. The joy of the harp ceases.", "anderson": "", "haweis": "", "noyes": "The mirth of tabrets ceaseth; The noise of them that rejoice is at an end; The joy of the harp ceaseth.", "webster": "The mirth of tabrets ceaseth, the noise of them that rejoice endeth, the joy of the harp ceaseth.", "vulgate": "cessavit gaudium tympanorum quievit sonitus laetantium conticuit dulcedo citharae;", "brenton": "The mirth of timbrels has ceased, the sound of the harp has ceased."}}, {"v": 9, "ref": "24:9", "o": "בַּ/שִּׁ֖יר לֹ֣א יִשְׁתּוּ יָ֑יִן יֵמַ֥ר שֵׁכָ֖ר לְ/שֹׁתָֽי/ו", "en": {"kjv": "They shall not drink wine with a song; strong drink shall be bitter to them that drink it.", "web": "They will not drink wine with a song. Strong drink will be bitter to those who drink it.", "bsb": "They no longer sing and drink wine; strong drink is bitter to those who consume it.", "asv": "They shall not drink wine with a song; strong drink shall be bitter to them that drink it.", "ylt": "With a song they drink not wine, Bitter is strong drink to those drinking it.", "dra": "They shall not drink wine with a song: the drink shall be bitter to them that drink it.", "bbe": "There is no more drinking of wine with a song; strong drink will be bitter to those who take it.", "geneva": "They shall not drinke wine with mirth: strong drinke shall be bitter to them that drinke it.", "wycliffe": "Thei schulen not drynke wyn; a bittere drynk schal be to hem that schulen drynke it.", "rotherham": "With a song, they drink not wine,—Bitter is strong drink, to them who drink it:", "darby": "They do not drink wine with a song; strong drink is bitter to them that drink it.", "twenty": "", "jps": "They drink not wine with a song; strong drink is bitter to them that drink it.", "acv": "They shall not drink wine with a song. Strong drink shall be bitter to those who drink it.", "anderson": "", "haweis": "", "noyes": "No more do they drink wine with the song; Strong drink is bitter to them that use it.", "webster": "They shall not drink wine with a song; strong drink shall be bitter to them that drink it.", "vulgate": "cum cantico non bibent vinum amara erit potio bibentibus illam;", "brenton": "They are ashamed, they have not drunk wine; strong drink has become bitter to them that drink it."}}, {"v": 10, "ref": "24:10", "o": "נִשְׁבְּרָ֖ה קִרְיַת תֹּ֑הוּ סֻגַּ֥ר כָּל בַּ֖יִת מִ/בּֽוֹא", "en": {"kjv": "The city of confusion is broken down: every house is shut up, that no man may come in.", "web": "The confused city is broken down. Every house is shut up, that no man may come in.", "bsb": "The city of chaos is shattered; every house is closed to entry.", "asv": "The waste city is broken down; every house is shut up, that no man may come in.", "ylt": "It was broken down--a city of emptiness, Shut hath been every house from entrance.", "dra": "The city of vanity is broken down, every house is shut up, no man cometh in.", "bbe": "The town is waste and broken down: every house is shut up, so that no man may come in.", "geneva": "The citie of vanitie is broken downe: euery house is shut vp, that no man may come in.", "wycliffe": "The citee of vanyte is al to-brokun; ech hous is closid, for no man entrith.", "rotherham": "Broken down is the city of desolation,—Shut up every house that it cannot be entered.", "darby": "The city of solitude is broken down; every house is shut up, so that none entereth in.", "twenty": "", "jps": "Broken down is the city of wasteness; every house is shut up, that none may come in.", "acv": "The waste city is broken down. Every house is shut up, that no man may come in.", "anderson": "", "haweis": "", "noyes": "The city of desolation is broken down; Every house is closed, so that none can enter.", "webster": "The city of confusion is broken down: every house is shut up, that no man may enter.", "vulgate": "adtrita est civitas vanitatis clausa est omnis domus nullo introeunte;", "brenton": "All the city has become desolate: one shall shut his house so that none shall enter."}}, {"v": 11, "ref": "24:11", "o": "צְוָחָ֥ה עַל הַ/יַּ֖יִן בַּֽ/חוּצ֑וֹת עָֽרְבָה֙ כָּל שִׂמְחָ֔ה גָּלָ֖ה מְשׂ֥וֹשׂ הָ/אָֽרֶץ", "en": {"kjv": "There is a crying for wine in the streets; all joy is darkened, the mirth of the land is gone.", "web": "There is a crying in the streets because of the wine. All joy is darkened. The mirth of the land is gone.", "bsb": "In the streets they cry out for wine. All joy turns to gloom; rejoicing is exiled from the land.", "asv": "There is a crying in the streets because of the wine; all joy is darkened, the mirth of the land is gone.", "ylt": "A cry over the wine is in out-places, Darkened hath been all joy, Removed hath been the joy of the land.", "dra": "There shall be a crying for wine in the streets: all mirth is forsaken: the joy of the earth is gone away.", "bbe": "There is a crying in the streets because of the wine; there is an end of all delight, the joy of the land is gone.", "geneva": "There is a crying for wine in the streetes: al ioy is darkened: the mirth of the world is gone away.", "wycliffe": "Cry schal be on wyn in streetis, al gladnesse is forsakun, the ioie of erthe is `takun awei.", "rotherham": "There is an outcry concerning wine in the streets,—Darkened is all joy, Departed the gladness of the earth.", "darby": "There is a crying for wine in the streets; all joy is darkened, the mirth of the land is gone;", "twenty": "", "jps": "There is a crying in the streets amidst the wine; all joy is darkened, the mirth of the land is gone.", "acv": "There is a crying in the streets because of the wine. All joy is darkened. The mirth of the land is gone.", "anderson": "", "haweis": "", "noyes": "There is a cry for wine in the streets; All gladness is departed; The mirth of the land is gone;", "webster": "[There] is a crying for wine in the streets; all joy is darkened, the mirth of the land is gone.", "vulgate": "clamor erit super vino in plateis deserta est omnis laetitia translatum est gaudium terrae;", "brenton": "There is a howling for the wine everywhere; all the mirth of the land has ceased, all the mirth of the land has departed."}}, {"v": 12, "ref": "24:12", "o": "נִשְׁאַ֥ר בָּ/עִ֖יר שַׁמָּ֑ה וּ/שְׁאִיָּ֖ה יֻכַּת שָֽׁעַר", "en": {"kjv": "In the city is left desolation, and the gate is smitten with destruction.", "web": "The city is left in desolation, and the gate is struck with destruction.", "bsb": "The city is left in ruins; its gate is reduced to rubble.", "asv": "In the city is left desolation, and the gate is smitten with destruction.", "ylt": "Left in the city is desolation, And with wasting is the gate smitten.", "dra": "Desolation is left in the city, and calamity shall oppress the gates.", "bbe": "In the town all is waste, and in the public place is destruction.", "geneva": "In the citie is left desolation, and the gate is smitten with destruction.", "wycliffe": "Desolacioun is left in the citee, and wretchidnesse schal oppresse the yatis.", "rotherham": "There is left in the city. desolation,—And to ruins, have been broken the gate.", "darby": "desolation remaineth in the city, and the gate is smitten, — a ruin.", "twenty": "", "jps": "In the city is left desolation, and the gate is smitten unto ruin.", "acv": "Desolation is left in the city, and the gate is smitten with destruction.", "anderson": "", "haweis": "", "noyes": "Desolation is left in the city, And the gate is smitten into ruins.", "webster": "In the city is left desolation, and the gate is smitten with destruction.", "vulgate": "relicta est in urbe solitudo et calamitas opprimet portas;", "brenton": "And cities shall be left desolate, and houses being left shall fall to ruin."}}, {"v": 13, "ref": "24:13", "o": "כִּ֣י כֹ֥ה יִהְיֶ֛ה בְּ/קֶ֥רֶב הָ/אָ֖רֶץ בְּ/ת֣וֹךְ הָֽ/עַמִּ֑ים כְּ/נֹ֣קֶף זַ֔יִת כְּ/עוֹלֵלֹ֖ת אִם כָּלָ֥ה בָצִֽיר", "en": {"kjv": "When thus it shall be in the midst of the land among the people, there shall be as the shaking of an olive tree, and as the gleaning grapes when the vintage is done.", "web": "For it will be so in the midst of the earth among the peoples, as the shaking of an olive tree, as the gleanings when the vintage is done.", "bsb": "So will it be on the earth and among the nations, like a harvested olive tree, like a gleaning after a grape harvest.", "asv": "For thus shall it be in the midst of the earth among the peoples, as the shaking of an olive-tree, as the gleanings when the vintage is done.", "ylt": "When thus it is in the heart of the land, In the midst of the peoples, As the compassing of the olive, As gleanings when harvest hath been finished,", "dra": "For it shall be thus in the midst of the earth, in the midst of the people, as if a few olives, that remain, should be shaken out of the olive tree: or grapes, when the vintage is ended.", "bbe": "For it will be in the heart of the earth among the peoples, like the shaking of an olive-tree, as the last of the grapes after the getting-in is done.", "geneva": "Surely thus shall it bee in the middes of the earth, among the people, as the shaking of an oliue tree, and as the grapes when the vintage is ended.", "wycliffe": "For these thingis schulen be in the myddis of erthe, in the myddis of puplis, as if a fewe fruitis of olyue trees that ben left ben schakun of fro the olyue tre, and racyns, whanne the vyndage is endid.", "rotherham": "When, thus, it shall be in the earth in the midst of the peoples, [There shall be] like the shaking of an olive-tree, like the going round to pick when closed is the harvest.", "darby": "For so will it be in the midst of the land among the peoples, as the shaking of an olive-tree, as the grape-gleanings when the vintage is done.", "twenty": "", "jps": "For thus shall it be in the midst of the earth, among the peoples, as at the beating of an olive-tree, as at the gleanings when the vintage is done.", "acv": "For thus shall it be in the midst of the earth among the peoples, as the shaking of an olive tree, as the gleanings when the vintage is done.", "anderson": "", "haweis": "", "noyes": "Yea, thus shall it be in the land, in the midst of the people, As when the olive-tree has been shaken; As the gleaning, when the vintage is ended.", "webster": "When thus it shall be in the midst of the land among the people, [there shall be] as the shaking of an olive-tree, [and] as the gleaning grapes when the vintage is done.", "vulgate": "quia haec erunt in medio terrae in medio populorum quomodo si paucae olivae quae remanserunt excutiantur ex olea et racemi cum fuerit finita vindemia;", "brenton": "All this shall be in the land in the midst of the nations, as if one should strip an olive tree, so shall they strip them; but when the vintage is done,"}}, {"v": 14, "ref": "24:14", "o": "הֵ֛מָּה יִשְׂא֥וּ קוֹלָ֖/ם יָרֹ֑נּוּ בִּ/גְא֣וֹן יְהוָ֔ה צָהֲל֖וּ מִ/יָּֽם", "en": {"kjv": "They shall lift up their voice, they shall sing for the majesty of the Lord, they shall cry aloud from the sea.", "web": "These shall lift up their voice. They will shout for the majesty of Yahweh. They cry aloud from the sea.", "bsb": "They raise their voices, they shout for joy; from the west they proclaim the majesty of the LORD.", "asv": "These shall lift up their voice, they shall shout; for the majesty of Jehovah they cry aloud from the sea.", "ylt": "They--they lift up their voice, They sing of the excellency of Jehovah, They have cried aloud from the sea.", "dra": "These shall lift up their voice, and shall give praise: when the Lord shall be glorified, they shall make a joyful noise from the sea.", "bbe": "But those will be making sounds of joy; they will be crying loudly from the sea for the glory of the Lord.", "geneva": "They shall lift vp their voyce: they shall shout for the magnificence of the Lord: they shall reioyce from the sea.", "wycliffe": "These men schulen reise her vois, and schulen preise, whanne the Lord schal be glorified; thei schulen schewe signes of gladnesse fro the see.", "rotherham": "They, shall lift up their voice—shall raise a tremulous note,—On account of the splendour of Yahweh, have they made a shrill cry, on the West;", "darby": "These shall lift up their voice, they shall shout for the majesty of Jehovah, they shall cry aloud from the sea.", "twenty": "", "jps": "Those yonder lift up their voice, they sing for joy; for the majesty of HaShem they shout from the sea:", "acv": "These shall lift up their voice. They shall shout. For the majesty of Jehovah they cry aloud from the sea.", "anderson": "", "haweis": "", "noyes": "These shall lift up their voice, and sing; Yea, for the majesty of Jehovah they shall shout from the sea.", "webster": "They shall lift up their voice, they shall sing for the majesty of the LORD, they shall cry aloud from the sea.", "vulgate": "hii levabunt vocem suam atque laudabunt cum glorificatus fuerit Dominus hinnient de mari;", "brenton": "these shall cry aloud; and they that are left on the land shall rejoice together in the glory of the Lord: the water of the sea shall be troubled."}}, {"v": 15, "ref": "24:15", "o": "עַל כֵּ֥ן בָּ/אֻרִ֖ים כַּבְּד֣וּ יְהוָ֑ה בְּ/אִיֵּ֣י הַ/יָּ֔ם שֵׁ֥ם יְהוָ֖ה אֱלֹהֵ֥י יִשְׂרָאֵֽל", "en": {"kjv": "Wherefore glorify ye the Lord in the fires, even the name of the Lord God of Israel in the isles of the sea.", "web": "Therefore glorify Yahweh in the east, even the name of Yahweh, the God of Israel, in the islands of the sea!", "bsb": "Therefore glorify the LORD in the east. Extol the name of the LORD, the God of Israel in the islands of the sea.", "asv": "Wherefore glorify ye Jehovah in the east, even the name of Jehovah, the God of Israel, in the isles of the sea.", "ylt": "Therefore in prosperity honour ye Jehovah, In isles of the sea, the name of Jehovah, God of Israel.", "dra": "Therefore glorify ye the Lord in instruction: the name of the Lord God of Israel in the islands of the sea.", "bbe": "Give praise to the Lord in the east, to the name of the Lord, the God of Israel, in the sea-lands.", "geneva": "Wherefore praise yee the Lord in the valleis, euen the Name of the Lord God of Israel, in the yles of the sea.", "wycliffe": "For this thing glorifie ye the Lord in techyngis; in the ilis of the see glorifie ye the name of the Lord God of Israel.", "rotherham": "For this cause, In the Regions of Light, give ye glory to Yahweh,—In the Coastlands of the Sea, unto the Name of Yahweh. God of Israel,", "darby": "Therefore glorify Jehovah in the east, the name of Jehovah, theGod of Israel, in the isles of the west.", "twenty": "", "jps": "'Therefore glorify ye HaShem in the regions of light, even the name of HaShem, the G-d of Israel, in the isles of the sea.'", "acv": "Therefore glorify ye Jehovah in the east, even the name of Jehovah, the God of Israel, in the isles of the sea.", "anderson": "", "haweis": "", "noyes": "Wherefore praise ye Jehovah in the East, The name of Jehovah, the God of Israel, in the isles of the sea!", "webster": "Wherefore glorify ye the LORD in the fires, [even] the name of the LORD God of Israel in the isles of the sea.", "vulgate": "propter hoc in doctrinis glorificate Dominum in insulis maris nomen Domini Dei Israhel;", "brenton": "Therefore shall the glory of the Lord be in the isles of the sea; the name of the Lord shall be glorious."}}, {"v": 16, "ref": "24:16", "o": "מִ/כְּנַ֨ף הָ/אָ֜רֶץ זְמִרֹ֤ת שָׁמַ֨עְנוּ֙ צְבִ֣י לַ/צַּדִּ֔יק וָ/אֹמַ֛ר רָזִי לִ֥/י רָֽזִי לִ֖/י א֣וֹי לִ֑/י בֹּגְדִ֣ים בָּגָ֔דוּ וּ/בֶ֥גֶד בּוֹגְדִ֖ים בָּגָֽדוּ", "en": {"kjv": "From the uttermost part of the earth have we heard songs, even glory to the righteous. But I said, My leanness, my leanness, woe unto me! the treacherous dealers have dealt treacherously; yea, the treacherous dealers have dealt very treacherously.", "web": "From the uttermost part of the earth have we heard songs. Glory to the righteous! But I said, “I pine away! I pine away! woe is me!” The treacherous have dealt treacherously. Yes, the treacherous have dealt very treacherously.", "bsb": "From the ends of the earth we hear singing: “Glory to the Righteous One.” But I said, “I am wasting away! I am wasting away! Woe is me.” The treacherous betray; the treacherous deal in treachery.", "asv": "From the uttermost part of the earth have we heard songs: Glory to the righteous. But I said, I pine away, I pine away, woe is me! the treacherous have dealt treacherously; yea, the treacherous have dealt very treacherously.", "ylt": "From the skirt of the earth we heard songs, The desire of the righteous. And I say, `Leanness is to me, Leanness is to me, woe is to me.' Treacherous dealers dealt treacherously, Yea, treachery, treacherous dealers dealt treacherously.", "dra": "From the ends of the earth we have heard praises, the glory of the just one. And I said: My secret to myself, my secret to myself, woe is me: the prevaricators have prevaricated, and with the prevarication of transgressors they have prevaricated.", "bbe": "From the farthest part of the earth comes the sound of songs, glory to the upright. But I said, I am wasting away, wasting away, the curse is on me! The false ones go on in their false way, yes, they go on acting falsely.", "geneva": "From the vttermost part of the earth wee haue heard praises, euen glory to the iust, and I sayd, My leanesse, my leanesse, woe is mee: the transgressours haue offended: yea, the transgressours haue grieuously offended.", "wycliffe": "Fro the endis of erthe we han herd heriyngis, the glorye of the iust. And Y seide, My priuyte to me, my pryuyte to me. Wo to me, trespassours han trespassid, and han trespassid bi trespassyng of brekeris of the lawe.", "rotherham": "From the uttermost part of the earth, melodies, have we heard—Beauty, to the righteous one! But I had said—Ruin to me! Ruin to me! Woe to me! Traitors, have betrayed, Yea traitorously, have traitors betrayed!", "darby": "From the end of the earth have we heard songs: Glory to the righteous! And I said, My leanness, my leanness, woe unto me! The treacherous have dealt treacherously; yea, the treacherous have dealt very treacherously.", "twenty": "", "jps": "From the uttermost part of the earth have we heard songs: 'Glory to the righteous.' But I say: I waste away, I waste away, woe is me! The treacherous deal treacherously; yea, the treacherous deal very treacherously.", "acv": "From the outermost part of the earth we have heard songs. Glory to the righteous. But I said, I pine away, I pine away. Woe is me! The treacherous have dealt treacherously, yea, the treacherous have dealt very treacherously.", "anderson": "", "haweis": "", "noyes": "From the end of the earth we hear songs: \"Glory to the righteous!\" But I cry, Alas, my wretchedness, my wretchedness! woe is me! The plunderers plunder; the plunderers seize the spoil.", "webster": "From the uttermost part of the earth have we heard songs, [even] glory to the righteous. But I said, My leanness, my leanness, woe to me! the treacherous dealers have dealt treacherously; yes, the treacherous dealers have dealt very treacherously.", "vulgate": "a finibus terrae laudes audivimus gloriam iusti et dixi secretum meum mihi secretum meum mihi vae mihi praevaricantes praevaricati sunt et praevaricatione transgressorum praevaricati sunt;", "brenton": "O Lord God of Israel, from the ends of the earth we have heard wonderful things, and there is hope to the godly: but they shall say, Woe to the despisers, that despise the law."}}, {"v": 17, "ref": "24:17", "o": "פַּ֥חַד וָ/פַ֖חַת וָ/פָ֑ח עָלֶ֖י/ךָ יוֹשֵׁ֥ב הָ/אָֽרֶץ", "en": {"kjv": "Fear, and the pit, and the snare, are upon thee, O inhabitant of the earth.", "web": "Fear, the pit, and the snare, are on you who inhabitant the earth.", "bsb": "Terror and pit and snare await you, O dweller of the earth.", "asv": "Fear, and the pit, and the snare, are upon thee, O inhabitant of the earth.", "ylt": "Fear, and a snare, and a gin, Are on thee, O inhabitant of the land.", "dra": "Fear, and the pit, and the snare are upon thee, O thou inhabitant of the earth.", "bbe": "Fear, and death, and the net, are come on you, O people of the earth.", "geneva": "Feare, and the pitte, and the snare are vpon thee, O inhabitant of the earth.", "wycliffe": "Ferdfulnesse, and a diche, and a snare on thee, that art a dwellere of erthe.", "rotherham": "Terror and pit and snare,—are upon thee, O inhabitant of the earth!", "darby": "Fear, and the pit, and the snare are upon thee, inhabitant of the land.", "twenty": "", "jps": "Terror, and the pit, and the trap, are upon thee, O inhabitant of the earth.", "acv": "Fear, and the pit, and the snare, are upon thee, O inhabitant of the earth.", "anderson": "", "haweis": "", "noyes": "The terror, the pit, and the snare Are upon thee, O inhabitant of the land!", "webster": "Fear, and the pit, and the snare, [are] upon thee, O inhabitant of the earth.", "vulgate": "formido et fovea et laqueus super te qui habitator es terrae;", "brenton": "Fear, and a pit, and a snare, are upon you that dwell on the earth."}}, {"v": 18, "ref": "24:18", "o": "וְֽ֠/הָיָה הַ/נָּ֞ס מִ/קּ֤וֹל הַ/פַּ֨חַד֙ יִפֹּ֣ל אֶל הַ/פַּ֔חַת וְ/הָֽ/עוֹלֶה֙ מִ/תּ֣וֹךְ הַ/פַּ֔חַת יִלָּכֵ֖ד בַּ/פָּ֑ח כִּֽי אֲרֻבּ֤וֹת מִ/מָּרוֹם֙ נִפְתָּ֔חוּ וַֽ/יִּרְעֲשׁ֖וּ מ֥וֹסְדֵי אָֽרֶץ", "en": {"kjv": "And it shall come to pass, that he who fleeth from the noise of the fear shall fall into the pit; and he that cometh up out of the midst of the pit shall be taken in the snare: for the windows from on high are open, and the foundations of the earth do shake.", "web": "It will happen that he who flees from the noise of the fear will fall into the pit; and he who comes up out of the midst of the pit will be taken in the snare; for the windows on high are opened, and the foundations of the earth tremble.", "bsb": "Whoever flees the sound of panic will fall into the pit, and whoever climbs from the pit will be caught in the snare. For the windows of heaven are open, and the foundations of the earth are shaken.", "asv": "And it shall come to pass, that he who fleeth from the noise of the fear shall fall into the pit; and he that cometh up out of the midst of the pit shall be taken in the snare: for the windows on high are opened, and the foundations of the earth tremble.", "ylt": "And it hath come to pass, He who is fleeing from the noise of the fear Doth fall into the snare, And he who is coming up from the midst of the snare, Is captured by the gin, For windows on high have been opened, And shaken are foundations of the land.", "dra": "And it shall come to pass, that he that shall flee from the noise of the fear, shall fall into the pit: and he that shall rid himself out of the pit, shall be taken in the snare: for the flood-gates from on high are opened, and the foundations of the earth shall be shaken.", "bbe": "And it will be that he who goes in flight from the sound of fear will be overtaken by death; and he who gets free from death will be taken in the net: for the windows on high are open, and the bases of the earth are shaking.", "geneva": "And hee that fleeth from the noyse of the feare, shall fall into the pit: and he that commeth vp out of the pit, shall be taken in the snare: for the windowes from on high are open, and the foundations of the earth doe shake.", "wycliffe": "And it schal be, he that schal fle fro the face of ferdfulnesse, schal falle in to the diche; and he that schal delyuere hym silf fro the dich, schal be holdun of the snare; for whi the wyndows of hiye thingis ben openyd, and the foundementis of erthe schulen be schakun togidere.", "rotherham": "So shall it be—He that fleeth from the sound of the terror! shall fall into the pit, And, he that getteth up out of the midst of the pit, shall be captured in the snare,—For, the windows on high, have opened, And shaken are the foundations of earth.", "darby": "And it shall come to pass, [that] he who fleeth from the sound of the fear shall fall into the pit; and he that cometh up out of the midst of the pit shall be taken in the snare; for the windows on high are open, and the foundations of the earth shake.", "twenty": "", "jps": "And it shall come to pass, that he who fleeth from the noise of the terror shall fall into the pit; and he that cometh up out of the midst of the pit shall be taken in the trap; for the windows on high are opened, and the foundations of the earth do shake;", "acv": "And it shall come to pass, that he who flees from the noise of the fear shall fall into the pit, and he who comes up out of the midst of the pit shall be taken in the snare. For the windows on high are opened, and the foundations of the earth tremble.", "anderson": "", "haweis": "", "noyes": "Whoso fleeth from the terror shall fall into the pit, And whoso escapeth from the pit, He shall be taken in the snare; For the floodgates of heaven are opened, And the foundations of the earth tremble.", "webster": "And it shall come to pass, [that] he who fleeth from the noise of the fear shall fall into the pit; and he that cometh up out of the midst of the pit shall be taken in the snare: for the windows from on high are open, and the foundations of the earth do shake.", "vulgate": "et erit qui fugerit a voce formidinis cadet in foveam et qui se explicuerit de fovea tenebitur laqueo quia cataractae de excelsis apertae sunt et concutientur fundamenta terrae;", "brenton": "And it shall come to pass, that he that flees from the fear shall fall into the pit; and he that comes up out of the pit shall be caught by the snare: for windows have been opened in heaven, and the foundations of the earth shall be shaken,"}}, {"v": 19, "ref": "24:19", "o": "רֹ֥עָה הִֽתְרֹעֲעָ֖ה הָ/אָ֑רֶץ פּ֤וֹר הִֽתְפּוֹרְרָה֙ אֶ֔רֶץ מ֥וֹט הִֽתְמוֹטְטָ֖ה אָֽרֶץ", "en": {"kjv": "The earth is utterly broken down, the earth is clean dissolved, the earth is moved exceedingly.", "web": "The earth is utterly broken. The earth is torn apart. The earth is shaken violently.", "bsb": "The earth is utterly broken apart, the earth is split open, the earth is shaken violently.", "asv": "The earth is utterly broken, the earth is rent asunder, the earth is shaken violently.", "ylt": "Utterly broken down hath been the land, Utterly broken hath been the land, Utterly moved hath been the land.", "dra": "With breaking shall the earth be broken, with crushing shall the earth be crushed, with trembling shall the earth be moved.", "bbe": "The earth is completely broken, it is parted in two, it is violently moved.", "geneva": "The earth is vtterly broken downe: the earth is cleane dissolued: the earth is mooued exceedingly.", "wycliffe": "The erthe schal be brokun with brekyng,", "rotherham": "The earth breaketh, breaketh,—The earth crasheth, crasheth, The earth tottereth, tottereth;", "darby": "The earth is utterly broken down, the earth is completely dissolved, the earth is violently moved.", "twenty": "", "jps": "The earth is broken, broken down, the earth is crumbled in pieces, the earth trembleth and tottereth;", "acv": "The earth is utterly broken. The earth is torn apart. The earth is shaken violently.", "anderson": "", "haweis": "", "noyes": "The earth is utterly broken down; The earth is shattered in pieces; The earth is violently moved from her place.", "webster": "The earth is utterly broken down, the earth is entirely dissolved, the earth is exceedingly moved.", "vulgate": "confractione confringetur terra contritione conteretur terra commotione commovebitur terra;", "brenton": "the earth shall be utterly confounded, and the earth shall be completely perplexed."}}, {"v": 20, "ref": "24:20", "o": "נ֣וֹעַ תָּנ֤וּעַ אֶ֨רֶץ֙ כַּ/שִּׁכּ֔וֹר וְ/הִֽתְנוֹדְדָ֖ה כַּ/מְּלוּנָ֑ה וְ/כָבַ֤ד עָלֶ֨י/הָ֙ פִּשְׁעָ֔/הּ וְ/נָפְלָ֖ה וְ/לֹא תֹסִ֥יף קֽוּם", "en": {"kjv": "The earth shall reel to and fro like a drunkard, and shall be removed like a cottage; and the transgression thereof shall be heavy upon it; and it shall fall, and not rise again.", "web": "The earth will stagger like a drunken man, and will sway back and forth like a hammock. Its disobedience will be heavy on it, and it will fall and not rise again.", "bsb": "The earth staggers like a drunkard and sways like a shack. Earth’s rebellion weighs it down, and it falls, never to rise again.", "asv": "The earth shall stagger like a drunken man, and shall sway to and fro like a hammock; and the transgression thereof shall be heavy upon it, and it shall fall, and not rise again.", "ylt": "Stagger greatly doth the land as a drunkard, And it hath been moved as a lodge, And heavy on it hath been its transgression, And it hath fallen, and addeth not to rise.", "dra": "With shaking shall the earth be shaken as a drunken man, and shall be removed as the tent of one night: and the iniquity thereof shall be heavy upon it, and it shall fall, and not rise again.", "bbe": "The earth will be moving uncertainly, like a man overcome by drink; it will be shaking like a tent; and the weight of its sin will be on it, crushing it down so that it will not get up again.", "geneva": "The earth shall reele to and from like a drunken man, and shall be remooued like a tent, and the iniquitie thereof shall be heauie vpon it: so that it shall fall, and rise no more.", "wycliffe": "the erthe schal be defoulid with defoulyng, the erthe schal be mouyd with mouyng, the erthe schal be schakun with schakyng, as a drunkun man.", "rotherham": "The earth staggereth—staggereth like a drunken man, And rocketh to and fro like a night-hut,—So shall be heavy upon her, her transgression, And she shall fall and not again rise.", "darby": "The earth reeleth to and fro like a drunkard, and is shaken like a night hut; and its transgression is heavy upon it; and it falleth and shall not rise again.", "twenty": "", "jps": "The earth reeleth to and fro like a drunken man, and swayeth to and fro as a lodge; and the transgression thereof is heavy upon it, and it shall fall, and not rise again.", "acv": "The earth shall stagger like a drunken man, and shall sway to and fro like a hammock. And the transgression of it shall be heavy upon it, and it shall fall, and not rise again.", "anderson": "", "haweis": "", "noyes": "The earth reeleth like a drunkard, It moveth to and fro like a hammock; For her iniquity lieth heavy upon her, And she shall fall and rise no more.", "webster": "The earth shall reel to and fro like a drunkard, and shall be removed like a cottage; and the transgression of it shall be heavy upon it; and it shall fall, and not rise again.", "vulgate": "agitatione agitabitur terra sicut ebrius et auferetur quasi tabernaculum unius noctis et gravabit eam iniquitas sua et corruet et non adiciet ut resurgat;", "brenton": "It reels as a drunkard and one oppressed with wine, and the earth shall be shaken as a storehouse of fruits; for iniquity has prevailed upon it, and it shall fall, and shall not be able to rise."}}, {"v": 21, "ref": "24:21", "o": "וְ/הָיָה֙ בַּ/יּ֣וֹם הַ/ה֔וּא יִפְקֹ֧ד יְהוָ֛ה עַל צְבָ֥א הַ/מָּר֖וֹם בַּ/מָּר֑וֹם וְ/עַל מַלְכֵ֥י הָ/אֲדָמָ֖ה עַל הָ/אֲדָמָֽה", "en": {"kjv": "And it shall come to pass in that day, that the Lord shall punish the host of the high ones that are on high, and the kings of the earth upon the earth.", "web": "It shall happen in that day that Yahweh will punish the army of the high ones on high, and the kings of the earth on the earth.", "bsb": "In that day the LORD will punish the host of heaven above and the kings of the earth below.", "asv": "And it shall come to pass in that day, that Jehovah will punish the host of the high ones on high, and the kings of the earth upon the earth.", "ylt": "And it hath come to pass, in that day, Jehovah layeth a charge on the host of the high place in the high place, And on the kings of the land on the land.", "dra": "And it shall come to pass, that in that day the Lord shall visit upon the host of heaven on high, and upon the kings of the earth, on the earth.", "bbe": "And in that day the Lord will send punishment on the army of the high ones on high, and on the kings of the earth on the earth.", "geneva": "And in that day shall the Lord visite the hoste aboue that is on hie, euen the Kinges of the world that are vpon the earth.", "wycliffe": "And it schal be takun awei, as the tabernacle of o nyyt, and the wickidnesse therof schal greue it; and it schal falle down, and it schal not adde, for to rise ayen. And it schal be, in that dai the Lord schal visite on the knyythod of heuene an hiy, and on the kyngis of erthe, that ben on erthe.", "rotherham": "And it shall be in that day, That Yahweh will bring punishment Upon the host of the height in the height,—And upon the kings of the ground on the ground.", "darby": "And it shall come to pass in that day, [that] Jehovah will punish the host of the high ones on high, and the kings of the earth upon the earth.", "twenty": "", "jps": "And it shall come to pass in that day, that HaShem will punish the host of the high heaven on high, and the kings of the earth upon the earth.", "acv": "And it shall come to pass in that day, that Jehovah will punish the host of the high ones on high, and the kings of the earth upon the earth.", "anderson": "", "haweis": "", "noyes": "In that day will Jehovah punish the host of the high ones that are on high, And the kings of the earth upon the earth.", "webster": "And it shall come to pass in that day, [that] the LORD shall punish the host of the high ones [that are] on high, and the kings of the earth upon the earth.", "vulgate": "et erit in die illa visitabit Dominus super militiam caeli in excelso et super reges terrae qui sunt super terram;", "brenton": "And God shall bring his hand upon the host of heaven, and upon the kings of the earth."}}, {"v": 22, "ref": "24:22", "o": "וְ/אֻסְּפ֨וּ אֲסֵפָ֤ה אַסִּיר֙ עַל בּ֔וֹר וְ/סֻגְּר֖וּ עַל מַסְגֵּ֑ר וּ/מֵ/רֹ֥ב יָמִ֖ים יִפָּקֵֽדוּ", "en": {"kjv": "And they shall be gathered together, as prisoners are gathered in the pit, and shall be shut up in the prison, and after many days shall they be visited.", "web": "They shall be gathered together, as prisoners are gathered in the pit, and shall be shut up in the prison; and after many days shall they be visited.", "bsb": "They will be gathered together like prisoners in a pit. They will be confined to a dungeon and punished after many days.", "asv": "And they shall be gathered together, as prisoners are gathered in the pit, and shall be shut up in the prison; and after many days shall they be visited.", "ylt": "And they have been gathered--A gathering of bound ones in a pit, And shut up they have been in a prison, And after a multitude of days are inspected.", "dra": "And they shall be gathered together as in the gathering of one bundle into the pit, and they shall be shut up there in prison: and after many days they shall be visited.", "bbe": "And they will be got together, like prisoners in the prison-house; and after a long time they will have their punishment.", "geneva": "And they shall be gathered together, as the prisoners in the pit: and they shall be shut vp in the prison, and after many daies shall they be visited.", "wycliffe": "And thei schulen be gaderid togidere in the gadering togidere of a bundel in to the lake, and thei schulen be closid there in prisoun; and aftir many daies thei schulen be visited.", "rotherham": "And they shall be swept together in a crowd, fettered for a pit, And shall be lowered into a dungeon,—And, after many days, shall they be punished.", "darby": "And they shall be brought together, [as] an assemblage of prisoners for the pit, and shall be shut up in prison, and after many days shall they be visited.", "twenty": "", "jps": "And they shall be gathered together, as prisoners are gathered in the dungeon, and shall be shut up in the prison, and after many days shall they be punished.", "acv": "And they shall be gathered together as prisoners are gathered in the pit, and shall be shut up in the prison. And after many days they shall be visited.", "anderson": "", "haweis": "", "noyes": "They shall be thrown together bound into the pit, And shall be shut up in the prison, But after many days shall they be visited.", "webster": "And they shall be gathered, [as] prisoners are gathered in the pit, and shall be shut up in the prison, and after many days shall they be visited.", "vulgate": "et congregabuntur in congregationem unius fascis in lacum et cludentur ibi in carcerem et post multos dies visitabuntur;", "brenton": "And they shall gather the multitude thereof into prisons, and they shall shut them into a strong hold: after many generations they shall be visited."}}, {"v": 23, "ref": "24:23", "o": "וְ/חָֽפְרָה֙ הַ/לְּבָנָ֔ה וּ/בוֹשָׁ֖ה הַֽ/חַמָּ֑ה כִּֽי מָלַ֞ךְ יְהוָ֣ה צְבָא֗וֹת בְּ/הַ֤ר צִיּוֹן֙ וּ/בִ/יר֣וּשָׁלִַ֔ם וְ/נֶ֥גֶד זְקֵנָ֖י/ו כָּבֽוֹד", "en": {"kjv": "Then the moon shall be confounded, and the sun ashamed, when the Lord of hosts shall reign in mount Zion, and in Jerusalem, and before his ancients gloriously.", "web": "Then the moon shall be confounded, and the sun ashamed; for Yahweh of Armies will reign on Mount Zion, and in Jerusalem; and before his elders will be glory.", "bsb": "The moon will be confounded and the sun will be ashamed; for the LORD of Hosts will reign on Mount Zion and in Jerusalem, and before His elders with great glory.", "asv": "Then the moon shall be confounded, and the sun ashamed; for Jehovah of hosts will reign in mount Zion, and in Jerusalem; and before his elders shall be glory.", "ylt": "And confounded hath been the moon, And ashamed hath been the sun, For reigned hath Jehovah of Hosts In mount Zion, and in Jerusalem, And over-against His elders--honour!", "dra": "And the moon shall blush, and the sun shall be ashamed, when the Lord of hosts shall reign in mount Sion, and in Jerusalem, and shall be glorified in the sight of his ancients.", "bbe": "Then the moon will be veiled, and the sun put to shame; for the Lord of armies will be ruling in Mount Zion and in Jerusalem, and before his judges he will let his glory be seen.", "geneva": "Then the moone shall be abashed, and the sunne ashamed, when the Lord of hostes shall reigne in mount Zion and in Ierusalem: and glory shalbe before his ancient men.", "wycliffe": "And the moone schal be aschamed, and the sunne schal be confoundid, whanne the Lord of oostis schal regne in the hil of Sion, and in Jerusalem, and schal be glorified in the siyt of hise eldre men.", "rotherham": "Then shall blush the silvery moon, Then turn pale the glowing sun,—Because Yahweh of hosts hath become king In Mount Zion And in Jerusalem, And before his Elders in glory,", "darby": "And the moon shall be confounded, and the sun ashamed; for Jehovah of hosts shall reign on mount Zion, and in Jerusalem, and before his ancients in glory.", "twenty": "", "jps": "Then the moon shall be confounded, and the sun ashamed; for HaShem of hosts will reign in mount Zion, and in Jerusalem, and before His elders shall be Glory.", "acv": "Then the moon shall be confounded, and the sun ashamed, for Jehovah of hosts will reign in mount Zion and in Jerusalem. And glory shall be before his elders.", "anderson": "", "haweis": "", "noyes": "The moon shall be confounded and the sun ashamed, When Jehovah of hosts shall reign in mount Zion and Jerusalem, And his glory shall be before his ancients.", "webster": "Then the moon shall be confounded, and the sun ashamed, when the LORD of hosts shall reign on mount Zion, and in Jerusalem, and before his ancients gloriously.", "vulgate": "et erubescet luna et confundetur sol cum regnaverit Dominus exercituum in monte Sion et in Hierusalem et in conspectu senum suorum fuerit glorificatus;", "brenton": "And the brick shall decay, and the wall shall fall; for the Lord shall reign from out of Sion, and out of Jerusalem, and shall be glorified before his elders."}}]}, {"c": 25, "verses": [{"v": 1, "ref": "25:1", "o": "יְהוָ֤ה אֱלֹהַ/י֙ אַתָּ֔ה אֲרֽוֹמִמְ/ךָ֙ אוֹדֶ֣ה שִׁמְ/ךָ֔ כִּ֥י עָשִׂ֖יתָ פֶּ֑לֶא עֵצ֥וֹת מֵֽ/רָח֖וֹק אֱמ֥וּנָה אֹֽמֶן", "en": {"kjv": "O Lord, thou art my God; I will exalt thee, I will praise thy name; for thou hast done wonderful things; thy counsels of old are faithfulness and truth.", "web": "Yahweh, you are my God. I will exalt you! I will praise your name, for you have done wonderful things, things planned long ago, in complete faithfulness and truth.", "bsb": "O LORD, You are my God! I will exalt You; I will praise Your name. For You have worked wonders— plans formed long ago— in perfect faithfulness.", "asv": "O Jehovah, thou art my God; I will exalt thee, I will praise thy name; for thou hast done wonderful things, even counsels of old, in faithfulness and truth.", "ylt": "O Jehovah, my God art Thou, I exalt Thee, I confess Thy name, For Thou hast done a wonderful thing, Counsels of old, stedfastness, O stedfast One.", "dra": "O Lord, thou art my God, I will exalt O thee, and give glory to thy name: for thou hast done wonderful things, thy designs of old faithful, amen.", "bbe": "O Lord, you are my God; I will give praise to you, I will give honour to your name; for you have done great acts of power; your purposes in the past have been made true and certain in effect.", "geneva": "O Lord, thou art my God: I will exalt thee, I will prayse thy Name: for thou hast done wonderfull things, according to the counsels of old, with a stable trueth.", "wycliffe": "Lord, thou art my God, Y schal enhaunse thee, and Y schal knouleche to thi name; for thou hast do marueils, thin elde feithful thouytis.", "rotherham": "O Yahweh! my God, thou art, I will exalt thee, I will praise thy Name, For thou hast done a wonderful thing,—Purposes of long ago Faithfulness in truth.", "darby": "Jehovah, thou art myGod: I will exalt thee; I will celebrate thy name, for thou hast done wonderful things; counsels of old [which are] faithfulness [and] truth.", "twenty": "", "jps": "O HaShem, Thou art my G-d, I will exalt Thee, I will praise Thy name, for Thou hast done wonderful things; even counsels of old, in faithfulness and truth.", "acv": "O Jehovah, thou are my God. I will exalt thee. I will praise thy name. For thou have done wonderful things, even counsels of old, in faithfulness and truth.", "anderson": "", "haweis": "", "noyes": "O Jehovah, thou art my God; I will exalt thee; I will praise thy name, For thou hast done wonderful things; Thine ancient purposes are faithfulness and truth.", "webster": "O LORD, thou [art] my God; I will exalt thee, I will praise thy name; for thou hast done wonderful [things]; [thy] counsels of old [are] faithfulness [and] truth.", "vulgate": "Domine Deus meus es tu exaltabo te confitebor nomini tuo quoniam fecisti mirabilia cogitationes antiquas fideles amen;", "brenton": "O Lord God, I will glorify thee, I will sing to thy name; for thou hast done wonderful things, even an ancient and faithful counsel. So be it."}}, {"v": 2, "ref": "25:2", "o": "כִּ֣י שַׂ֤מְתָּ מֵ/עִיר֙ לַ/גָּ֔ל קִרְיָ֥ה בְצוּרָ֖ה לְ/מַפֵּלָ֑ה אַרְמ֤וֹן זָרִים֙ מֵ/עִ֔יר לְ/עוֹלָ֖ם לֹ֥א יִבָּנֶֽה", "en": {"kjv": "For thou hast made of a city an heap; of a defenced city a ruin: a palace of strangers to be no city; it shall never be built.", "web": "For you have made a city into a heap, a fortified city into a ruin, a palace of strangers to be no city. It will never be built.", "bsb": "Indeed, You have made the city a heap of rubble, the fortified town a ruin. The fortress of strangers is a city no more; it will never be rebuilt.", "asv": "For thou hast made of a city a heap, of a fortified city a ruin, a palace of strangers to be no city; it shall never be built.", "ylt": "For Thou didst make of a city a heap, Of a fenced city a ruin, A high place of strangers from being a city, To the age it is not built.", "dra": "For thou hast reduced the city to a heap, the strong city to ruin, the house of strangers, to be no city, and to be no more built up for ever.", "bbe": "For you have made a town a waste place: a strong town a mass of broken walls; the tower of the men of pride has come to an end; it will never be put up again.", "geneva": "For thou hast made of a citie an heape, of a strong citie, a ruine: euen the palace of strangers of a citie, it shall neuer be built.", "wycliffe": "Amen. For thou hast set the citee in to a biriel, a strong citee in to fallyng, the hous of aliens, that it be not a citee, and be not bildid with outen ende.", "rotherham": "For thou hast made, of a citadel, a mound, of a defenced city, a ruin,—palaces for foreigners to be no city, To times age-abiding, shall it not be built.", "darby": "For thou hast made of the city a heap, of the fortified town a ruin, the palace of strangers to be no city; it shall never be built up.", "twenty": "", "jps": "For Thou hast made of a city a heap, of a fortified city a ruin; a castle of strangers to be no city, it shall never be built.", "acv": "For thou have made of a city a heap, of a fortified city a ruin, a palace of strangers to be no city. It shall never be built.", "anderson": "", "haweis": "", "noyes": "Thou hast made the city a heap; The fortified city a ruin. The palace of the barbarians is to be no more a city! It shall never be built again.", "webster": "For thou hast made of a city a heap; [of] a fortified city a ruin: a palace of strangers to be no city; it shall never be built.", "vulgate": "quia posuisti civitatem in tumulum urbem fortem in ruinam domum alienorum ut non sit civitas et in sempiternum non aedificetur;", "brenton": "For thou hast made cities a heap, even cities made strong that their foundations should not fall: the city of ungodly men shall not be built for ever."}}, {"v": 3, "ref": "25:3", "o": "עַל כֵּ֖ן יְכַבְּד֣וּ/ךָ עַם עָ֑ז קִרְיַ֛ת גּוֹיִ֥ם עָרִיצִ֖ים יִירָאֽוּ/ךָ", "en": {"kjv": "Therefore shall the strong people glorify thee, the city of the terrible nations shall fear thee.", "web": "Therefore a strong people will glorify you. A city of awesome nations will fear you.", "bsb": "Therefore, a strong people will honor You. The cities of ruthless nations will revere You.", "asv": "Therefore shall a strong people glorify thee; a city of terrible nations shall fear thee.", "ylt": "Therefore honour Thee do a strong people, A city of the terrible nations feareth Thee.", "dra": "Therefore shall a strong people praise thee, the city of mighty nations shall fear thee.", "bbe": "For this cause will the strong people give glory to you, the town of the cruel ones will be in fear of you.", "geneva": "Therefore shall the mightie people giue glory vnto thee: the citie of the strong nations shall feare thee.", "wycliffe": "For this thyng a strong puple schal herie thee, the citee of strong folkis schal drede thee.", "rotherham": "For this cause! shall glorify thee—a strong people, the city of tyrannous nations shall revere thee;", "darby": "Therefore shall the mighty people glorify thee, the city of terrible nations shall fear thee.", "twenty": "", "jps": "Therefore shall the strong people glorify Thee, the city of the terrible nations shall fear Thee.", "acv": "Therefore a strong people shall glorify thee, a city of oppressive nations shall fear thee.", "anderson": "", "haweis": "", "noyes": "Therefore shall mighty kingdoms praise thee; The cities of the terrible nations shall honor thee;", "webster": "Therefore shall the strong people glorify thee, the city of the terrible nations shall fear thee.", "vulgate": "super hoc laudabit te populus fortis civitas gentium robustarum timebit te;", "brenton": "Therefore shall the poor people bless thee, and cities of injured men shall bless thee."}}, {"v": 4, "ref": "25:4", "o": "כִּֽי הָיִ֨יתָ מָע֥וֹז לַ/דָּ֛ל מָע֥וֹז לָ/אֶבְי֖וֹן בַּ/צַּר ל֑/וֹ מַחְסֶ֤ה מִ/זֶּ֨רֶם֙ צֵ֣ל מֵ/חֹ֔רֶב כִּ֛י ר֥וּחַ עָרִיצִ֖ים כְּ/זֶ֥רֶם קִֽיר", "en": {"kjv": "For thou hast been a strength to the poor, a strength to the needy in his distress, a refuge from the storm, a shadow from the heat, when the blast of the terrible ones is as a storm against the wall.", "web": "For you have been a stronghold to the poor, a stronghold to the needy in his distress, a refuge from the storm, a shade from the heat, when the blast of the dreaded ones is like a storm against the wall.", "bsb": "For You have been a refuge for the poor, a stronghold for the needy in distress, a refuge from the storm, a shade from the heat. For the breath of the ruthless is like rain against a wall,", "asv": "For thou hast been a stronghold to the poor, a stronghold to the needy in his distress, a refuge from the storm, a shade from the heat, when the blast of the terrible ones is as a storm against the wall.", "ylt": "For Thou hast been a stronghold for the poor, A stronghold for the needy in his distress, A refuge from storm, a shadow from heat, When the spirit of the terrible is as a storm--a wall.", "dra": "Because thou hast been a strength to the poor, a strength to the needy in his distress: a refuge from the whirlwind, a shadow from the heat. For the blast of the mighty is like a whirlwind beating against a wall.", "bbe": "For you have been a strong place for the poor and the crushed in their trouble, a safe place from the storm, a shade from the heat, when the wrath of the cruel ones is like a winter storm.", "geneva": "For thou hast bene a strength vnto the poore, euen a strength to the needie in his trouble, a refuge against the tempest, a shadow against the heate: for the blaste of the mightie is like a storme against the wall.", "wycliffe": "For thou art maad strengthe to a pore man, strengthe to a nedi man in his tribulacioun, hope fro whirlwynd, a schadewyng place fro heete; for whi the spirit of stronge men is as a whirlewynd hurlynge the wal.", "rotherham": "For thou didst become A refuge to the weak. A refuge to the needy, when distress was upon him,—A shelter from the storm. A shade from the heat, When the blast of tyrants was like a storm against a wall.", "darby": "For thou hast been a fortress to the poor, a fortress for the needy in his distress, a refuge from the storm, a shadow from the heat: for the blast of the terrible ones [has been] as the storm [against] a wall.", "twenty": "", "jps": "For Thou hast been a stronghold to the poor, a stronghold to the needy in his distress, a refuge from the storm, a shadow from the heat; for the blast of the terrible ones was as a storm against the wall.", "acv": "For thou have been a stronghold to a poor man, a stronghold to a needy man in his distress, a refuge from the storm, a shade from the heat, when the blast of the oppressors is as a storm against the wall.", "anderson": "", "haweis": "", "noyes": "For thou hast been a defence to the poor; A defence to the needy in his distress; A refuge from the storm, a shadow from the heat, When the rage of tyrants was like a storm against a wall.", "webster": "For thou hast been a defense to the poor, a defense to the needy in his distress, a refuge from the storm, a shade from the heat, when the blast of the terrible ones [is] as a storm [against] the wall.", "vulgate": "quia factus es fortitudo pauperi fortitudo egeno in tribulatione sua spes a turbine umbraculum ab aestu spiritus enim robustorum quasi turbo inpellens parietem;", "brenton": "For thou hast been a helper to every lowly city, and a shelter to them that were disheartened by reason of poverty: thou shalt deliver them from wicked men: thou hast been a shelter of them that thirst, and a refreshing air to injured men."}}, {"v": 5, "ref": "25:5", "o": "כְּ/חֹ֣רֶב בְּ/צָי֔וֹן שְׁא֥וֹן זָרִ֖ים תַּכְנִ֑יעַ חֹ֚רֶב בְּ/צֵ֣ל עָ֔ב זְמִ֥יר עָֽרִיצִ֖ים יַעֲנֶֽה", "en": {"kjv": "Thou shalt bring down the noise of strangers, as the heat in a dry place; even the heat with the shadow of a cloud: the branch of the terrible ones shall be brought low.", "web": "As the heat in a dry place will you bring down the noise of strangers; as the heat by the shade of a cloud, the song of the dreaded ones will be brought low.", "bsb": "like heat in a dry land. You subdue the uproar of foreigners. As the shade of a cloud cools the heat, so the song of the ruthless is silenced.", "asv": "As the heat in a dry place wilt thou bring down the noise of strangers; as the heat by the shade of a cloud, the song of the terrible ones shall be brought low.", "ylt": "As heat in a dry place, The noise of strangers Thou humblest, Heat with the shadow of a thick cloud, The singing of the terrible is humbled.", "dra": "Thou shalt bring down the tumult of strangers, as heat in thirst: and as with heat under a burning cloud, thou shalt make the branch of the mighty to wither away.", "bbe": "As heat by the shade of a cloud, the noise of the men of pride has been made quiet by you; as heat by the shade of a cloud, the song of the cruel ones has been stopped.", "geneva": "Thou shalt bring downe the noyse of the strangers, as the heate in a drie place: he wil bring downe the song of the mightie, as the heate in the shadowe of a cloude.", "wycliffe": "As bi heete in thirst, thou schalt make meke the noise of aliens; and as bi heete vndur a cloude brennynge, thou schalt make the siouns of stronge men to fade.", "rotherham": "As heat in a desert, the pomp of foreigners, wilt thou subdue,—Heat—with the shade of a cloud, The song of tyrants! become low.", "darby": "Thou hast subdued the tumult of strangers, as the heat in a dry place; [as] the heat, by the shadow of a cloud, [so] the song of the terrible ones is brought low.", "twenty": "", "jps": "As the heat in a dry place, Thou didst subdue the noise of strangers; as the heat by the shadow of a cloud, the song of the terrible ones was brought low.", "acv": "As the heat in a dry place thou will bring down the noise of strangers, as the heat by the shade of a cloud, the song of the oppressors shall be brought low.", "anderson": "", "haweis": "", "noyes": "As heat in a dry land is made to vanish, So thou puttest down the tumult of the barbarians; As heat is allayed by a thick cloud, So the triumph of the tyrants is brought low.", "webster": "Thou wilt bring down the noise of strangers, as the heat in a dry place; [even] the heat with the shade of a cloud: the branch of the terrible ones shall be brought low.", "vulgate": "sicut aestum in siti tumultum alienorum humiliabis et quasi calore sub nube torrente propaginem fortium marcescere facies;", "brenton": "We were as faint-hearted men thirsting in Sion, by reason of ungodly men to whom thou didst deliver us."}}, {"v": 6, "ref": "25:6", "o": "וְ/עָשָׂה֩ יְהוָ֨ה צְבָא֜וֹת לְ/כָל הָֽ/עַמִּים֙ בָּ/הָ֣ר הַ/זֶּ֔ה מִשְׁתֵּ֥ה שְׁמָנִ֖ים מִשְׁתֵּ֣ה שְׁמָרִ֑ים שְׁמָנִים֙ מְמֻ֣חָיִ֔ם שְׁמָרִ֖ים מְזֻקָּקִֽים", "en": {"kjv": "And in this mountain shall the Lord of hosts make unto all people a feast of fat things, a feast of wines on the lees, of fat things full of marrow, of wines on the lees well refined.", "web": "In this mountain, Yahweh of Armies will make all peoples a feast of fat things, a feast of choice wines, of fat things full of marrow, of well refined choice wines.", "bsb": "On this mountain the LORD of Hosts will prepare a banquet for all the peoples, a feast of aged wine, of choice meat, of finely aged wine.", "asv": "And in this mountain will Jehovah of hosts make unto all peoples a feast of fat things, a feast of wines on the lees, of fat things full of marrow, of wines on the lees well refined.", "ylt": "And made hath Jehovah of Hosts, For all the peoples in this mount, A banquet of fat things, a banquet of preserved things, Fat things full of marrow, preserved things refined.", "dra": "And the Lord of hosts shall make unto all people in this mountain, a feast of fat things, a feast of wine, of fat things full of marrow, of wine purified from the lees.", "bbe": "And in this mountain will the Lord of armies make for all peoples a feast of good things, a feast of wines long stored, of good things sweet to the taste, of wines long kept and tested.", "geneva": "And in this mountaine shall the Lord of hostes make vnto all people a feast of fat thinges, euen a feast of fined wines, and of fat thinges full of marow, of wines fined and purified.", "wycliffe": "And the Lord of oostis schal make in this hil to alle puplis the feeste of fatte thingis, the feeste of vyndage of fatte thingis ful of merow, of vyndage wel fyned.", "rotherham": "Then will Yahweh of hosts prepare for all the peoples in this mountain, A banquet of fat things, A banquet of old wines,—Of fat things full of marrow, Of old wines well refined;", "darby": "And in this mountain will Jehovah of hosts make unto all peoples a feast of fat things, a feast of wines on the lees, of fat things full of marrow, of wines on the lees well refined.", "twenty": "", "jps": "And in this mountain will HaShem of hosts make unto all peoples a feast of fat things, a feast of wines on the lees, of fat things full of marrow, of wines on the lees well refined.", "acv": "And in this mountain Jehovah of hosts will make to all peoples a feast of fat things, a feast of wines on the dregs, of fat things full of marrow, of wines on the dregs well refined.", "anderson": "", "haweis": "", "noyes": "Then in this mountain shall Jehovah of hosts prepare for all nations A feast of fat things, and wines kept on the lees; Of fat things full of marrow, of wines kept on the lees well refined.", "webster": "And on this mountain will the LORD of hosts make to all people a feast of fat things, a feast of wines on the lees, of fat things full of marrow, of wines on the lees well refined.", "vulgate": "et faciet Dominus exercituum omnibus populis in monte hoc convivium pinguium convivium vindemiae pinguium medullatorum vindemiae defecatae;", "brenton": "And the Lord of hosts shall make a feast for all the nations: on this mount they shall drink gladness, they shall drink wine:"}}, {"v": 7, "ref": "25:7", "o": "וּ/בִלַּע֙ בָּ/הָ֣ר הַ/זֶּ֔ה פְּנֵֽי הַ/לּ֥וֹט הַ/לּ֖וֹט עַל כָּל הָֽ/עַמִּ֑ים וְ/הַ/מַּסֵּכָ֥ה הַ/נְּסוּכָ֖ה עַל כָּל הַ/גּוֹיִֽם", "en": {"kjv": "And he will destroy in this mountain the face of the covering cast over all people, and the vail that is spread over all nations.", "web": "He will destroy in this mountain the surface of the covering that covers all peoples, and the veil that is spread over all nations.", "bsb": "On this mountain He will swallow up the shroud that enfolds all peoples, the sheet that covers all nations;", "asv": "And he will destroy in this mountain the face of the covering that covereth all peoples, and the veil that is spread over all nations.", "ylt": "And swallowed up hath He in this mountain The face of the wrapping that is wrapped over all the peoples, And of the covering that is spread over all the nations.", "dra": "And he shall destroy in this mountain the face of the bond with which all people were tied, and the web that he began over all nations.", "bbe": "And in this mountain he will put an end to the shade covering the face of all peoples, and the veil which is stretched over all nations.", "geneva": "And he will destroy in this mountaine the couering that couereth all people, and the vaile that is spread vpon all nations.", "wycliffe": "And he schal caste doun in this hil the face of boond, boundun togidere on alle puplis, and the web which he weuyde on alle naciouns.", "rotherham": "And he will swallow up in this mountain, The mask of the veil, the veil that is upon all the peoples,—And the web that is woven over all the nations.", "darby": "And he will destroy in this mountain the face of the veil which veileth all the peoples, and the covering that is spread over all the nations.", "twenty": "", "jps": "And He will destroy in this mountain the face of the covering that is cast over all peoples, and the veil that is spread over all nations.", "acv": "And he will destroy on this mountain the face of the covering that covers all peoples, and the veil that is spread over all nations.", "anderson": "", "haweis": "", "noyes": "He will destroy in this mountain the covering that was cast over all people, And the veil that was spread over all nations.", "webster": "And he will destroy on this mountain the face of the covering cast over all people, and the vail [that is] spread over all nations.", "vulgate": "et praecipitabit in monte isto faciem vinculi conligati super omnes populos et telam quam orditus est super universas nationes;", "brenton": "they shall anoint themselves with ointment in this mountain. Impart thou all these things to the nations; for this is God's counsel upon all the nations."}}, {"v": 8, "ref": "25:8", "o": "בִּלַּ֤ע הַ/מָּ֨וֶת֙ לָ/נֶ֔צַח וּ/מָחָ֨ה אֲדֹנָ֧/י יְהוִ֛ה דִּמְעָ֖ה מֵ/עַ֣ל כָּל פָּנִ֑ים וְ/חֶרְפַּ֣ת עַמּ֗/וֹ יָסִיר֙ מֵ/עַ֣ל כָּל הָ/אָ֔רֶץ כִּ֥י יְהוָ֖ה דִּבֵּֽר", "en": {"kjv": "He will swallow up death in victory; and the Lord God will wipe away tears from off all faces; and the rebuke of his people shall he take away from off all the earth: for the Lord hath spoken it.", "web": "He has swallowed up death forever! The Lord Yahweh will wipe away tears from off all faces. He will take the reproach of his people away from off all the earth, for Yahweh has spoken it.", "bsb": "He will swallow up death forever. The Lord GOD will wipe away the tears from every face and remove the disgrace of His people from the whole earth. For the LORD has spoken.", "asv": "He hath swallowed up death for ever; and the Lord Jehovah will wipe away tears from off all faces; and the reproach of his people will he take away from off all the earth: for Jehovah hath spoken it.", "ylt": "He hath swallowed up death in victory, And wiped hath the Lord Jehovah, The tear from off all faces, And the reproach of His people He turneth aside from off all the earth, For Jehovah hath spoken.", "dra": "He shall cast death down headlong for ever: and the Lord God shall wipe away tears from every face, and the reproach of his people he shall take away from off the whole earth: for the Lord hath spoken it.", "bbe": "He has put an end to death for ever; and the Lord God will take away all weeping; and he will put an end to the shame of his people in all the earth: for the Lord has said it.", "geneva": "He wil destroy death for euer: and the Lord God wil wipe away the teares from all faces, and the rebuke of his people will he take away out of all the earth: for the Lord hath spoken it.", "wycliffe": "And he schal caste doun deth with outen ende, and the Lord God schal do awey ech teer fro ech face; and he schal do awei the schenschipe of his puple fro ech lond; for the Lord spak.", "rotherham": "Having swallowed up death itself victoriously, My Lord, Yahweh, will wipe away, tears from off all faces,—And the reproach of his own people, will he remove from off all the earth, For, Yahweh, hath spoken.", "darby": "He will swallow up death in victory. And the Lord Jehovah will wipe away tears from off all faces; and the reproach of his people will he take away from off all the earth: for Jehovah hath spoken.", "twenty": "", "jps": "He will swallow up death for ever; and the L-rd GOD will wipe away tears from off all faces; and the reproach of His people will He take away from off all the earth; for HaShem hath spoken it.", "acv": "He will swallow up death in victory, and the lord Jehovah will wipe away tears from off all faces. And he will take away the reproach of his people from off all the earth. For Jehovah has spoken it.", "anderson": "", "haweis": "", "noyes": "He will destroy death forever; The Lord Jehovah will wipe away the tears from all faces, And the reproach of his people will he take away from the whole earth; For Jehovah hath said it.", "webster": "He will swallow up death in victory; and the Lord GOD will wipe away tears from off all faces; and the rebuke of his people will he remove from all the earth: for the LORD hath spoken [it].", "vulgate": "praecipitabit mortem in sempiternum et auferet Dominus Deus lacrimam ab omni facie et obprobrium populi sui auferet de universa terra quia Dominus locutus est;", "brenton": "Death has prevailed and swallowed men up; but again the Lord God has taken away every tear from every face. He has taken away the reproach of his people from all the earth: for the mouth of the Lord has spoken it."}}, {"v": 9, "ref": "25:9", "o": "וְ/אָמַר֙ בַּ/יּ֣וֹם הַ/ה֔וּא הִנֵּ֨ה אֱלֹהֵ֥י/נוּ זֶ֛ה קִוִּ֥ינוּ ל֖/וֹ וְ/יֽוֹשִׁיעֵ֑/נוּ זֶ֤ה יְהוָה֙ קִוִּ֣ינוּ ל֔/וֹ נָגִ֥ילָה וְ/נִשְׂמְחָ֖ה בִּ/ישׁוּעָתֽ/וֹ", "en": {"kjv": "And it shall be said in that day, Lo, this is our God; we have waited for him, and he will save us: this is the Lord; we have waited for him, we will be glad and rejoice in his salvation.", "web": "It shall be said in that day, “Behold, this is our God! We have waited for him, and he will save us! This is Yahweh! We have waited for him. We will be glad and rejoice in his salvation!”", "bsb": "And in that day it will be said, “Surely this is our God; we have waited for Him, and He has saved us. This is the LORD for whom we have waited. Let us rejoice and be glad in His salvation.”", "asv": "And it shall be said in that day, Lo, this is our God; we have waited for him, and he will save us: this is Jehovah; we have waited for him, we will be glad and rejoice in his salvation.", "ylt": "And one hath said in that day, `Lo, this is our God, We waited for Him, and He saveth us, This is Jehovah, we have waited for Him, We joy and rejoice in His salvation.'", "dra": "And they shall say in that day: Lo, this is our God, we have waited for him, and he will save us: this is the Lord, we have patiently waited for him, we shall rejoice and be joyful in his salvation.", "bbe": "And in that day it will be said, See, this is our God; we have been waiting for him, and he will be our saviour: this is the Lord in whom is our hope; we will be glad and have delight in his salvation.", "geneva": "And in that day shall men say, Loe, this is our God: we haue waited for him, and he wil saue vs. This is the Lord, we haue waited for him: we will reioyce and be ioyfull in his saluation.", "wycliffe": "And thei schulen seie in that dai, Lo! this is oure God; we abididen hym, and he schal saue vs; this is the Lord; we suffriden him, and we schulen make ful out ioie, and schulen be glad in his helthe.", "rotherham": "So shall it be said, in that day, Lo! our God, is this! We waited for him, that he might save us,—This, is Yahweh! We waited for him, Let us exult and rejoice in his salvation.", "darby": "And it shall be said in that day, Behold, this is ourGod; we have waited for him, and he will save us: this is Jehovah, we have waited for him; we will be glad and rejoice in his salvation.", "twenty": "", "jps": "And it shall be said in that day: 'Lo, this is our G-d, for whom we waited, that He might save us; this is HaShem, for whom we waited, we will be glad and rejoice in His salvation.'", "acv": "And it shall be said in that day, Lo, this is our God. We have waited for him, and he will save us. This is Jehovah. We have waited for him. We will be glad and rejoice in his salvation.", "anderson": "", "haweis": "", "noyes": "In that day shall men say, \"Behold, this is our God; We waited for him, and he hath saved us; This is Jehovah, for whom we waited; Let us rejoice and exult in his salvation.\"", "webster": "And it shall be said in that day, Lo, this [is] our God; we have waited for him, and he will save us: this is the LORD, we have waited for him, we will be glad and rejoice in his salvation.", "vulgate": "et dicet in die illa ecce Deus noster iste expectavimus eum et salvabit nos iste Dominus sustinuimus eum exultabimus et laetabimur in salutari eius;", "brenton": "And in that day they shall say, behold our God in whom we have trusted, and he shall save us: this is the Lord; we have waited for him, and we have exulted, and will rejoice in our salvation."}}, {"v": 10, "ref": "25:10", "o": "כִּֽי תָנ֥וּחַ יַד יְהוָ֖ה בָּ/הָ֣ר הַ/זֶּ֑ה וְ/נָ֤דוֹשׁ מוֹאָב֙ תַּחְתָּ֔י/ו כְּ/הִדּ֥וּשׁ מַתְבֵּ֖ן ב/מי בְּמ֥וֹ מַדְמֵנָֽה", "en": {"kjv": "For in this mountain shall the hand of the Lord rest, and Moab shall be trodden down under him, even as straw is trodden down for the dunghill.", "web": "For in this mountain the hand of Yahweh will rest. Moab will be trodden down in his place, even like straw is trodden down in the water of the dunghill.", "bsb": "For the hand of the LORD will rest on this mountain. But Moab will be trampled in his place as straw is trodden into the dung pile.", "asv": "For in this mountain will the hand of Jehovah rest; and Moab shall be trodden down in his place, even as straw is trodden down in the water of the dunghill.", "ylt": "For rest doth the hand of Jehovah on this mountain, And trodden down is Moab under Him, As trodden down is straw on a dunghill.", "dra": "For the hand of the Lord shall rest in this mountain: and Moab shall be trodden down under him, as straw is broken in pieces with the wain.", "bbe": "For in this mountain will the hand of the Lord come to rest, and Moab will be crushed down in his place, even as the dry stems of the grain are crushed under foot in the waste place.", "geneva": "For in this mountaine shall the hand of the Lord rest, and Moab shalbe threshed vnder him, euen as strawe is thresshed in Madmenah.", "wycliffe": "For whi the hond of the Lord schal reste in this hil, and Moab schal be threischid vndur hym, as chaffis ben stampid in a wayn.", "rotherham": "For the hand of Yahweh will settle down in this mountain,—Then shall Moab be trodden down in its place, Like the treading down of a strawheap in the water of a dunghill;", "darby": "For in this mountain shall the hand of Jehovah rest, and Moab shall be trodden down under him, as straw is trodden down in the dunghill;", "twenty": "", "jps": "For in this mountain will the hand of HaShem rest, and Moab shall be trodden down in his place, even as straw is trodden down in the dunghill.", "acv": "For the hand of Jehovah will rest on this mountain. And Moab shall be trodden down in his place, even as straw is trodden down in the water of the dunghill.", "anderson": "", "haweis": "", "noyes": "For the hand of Jehovah shall rest upon this mountain, And Moab shall be trodden down in his place, As straw is trodden down in a dung-pool.", "webster": "For on this mountain shall the hand of the LORD rest, and Moab shall be trodden down under him, even as straw is trodden down for the dunghill.", "vulgate": "quia requiescet manus Domini in monte isto et triturabitur Moab sub eo sicuti teruntur paleae in plaustro;", "brenton": "God will give rest on this mountain, and the country of Moab shall be trodden down, as they tread the floor with waggons."}}, {"v": 11, "ref": "25:11", "o": "וּ/פֵרַ֤שׂ יָדָי/ו֙ בְּ/קִרְבּ֔/וֹ כַּ/אֲשֶׁ֛ר יְפָרֵ֥שׂ הַ/שֹּׂחֶ֖ה לִ/שְׂח֑וֹת וְ/הִשְׁפִּיל֙ גַּֽאֲוָת֔/וֹ עִ֖ם אָרְבּ֥וֹת יָדָֽי/ו", "en": {"kjv": "And he shall spread forth his hands in the midst of them, as he that swimmeth spreadeth forth his hands to swim: and he shall bring down their pride together with the spoils of their hands.", "web": "He will spread out his hands in its midst, like one who swims spreads out hands to swim, but his pride will be humbled together with the craft of his hands.", "bsb": "He will spread out his hands within it, as a swimmer spreads his arms to swim. His pride will be brought low, despite the skill of his hands.", "asv": "And he shall spread forth his hands in the midst thereof, as he that swimmeth spreadeth forth his hands to swim; but Jehovah will lay low his pride together with the craft of his hands.", "ylt": "And he spread out his hands in its midst, As spread out doth the swimmer to swim; And He hath humbled his excellency With the machinations of his hands.", "dra": "And he shall stretch forth his hands under him, as he that swimmeth stretcheth forth his hands to swim: and he shall bring down his glory with the dashing of his hands.", "bbe": "And if he puts out his hands, like a man stretching out his hands in swimming, the Lord will make low his pride, however expert his designs.", "geneva": "And he shall stretche out his hande in the middes of them (as he that swimmeth, stretcheth them out to swimme) and with the strength of his handes shall he bring downe their pride.", "wycliffe": "And he schal stretche forth hise hondis vndur hym, as a swymmere stretchith forth to swymme; and he schal make low the glorye of him with hurtlyng doun of hise hondis.", "rotherham": "Should he spread forth his hands in the midst thereof, As a swimmer spreadeth forth to swim, Then would be laid low his pride, together with the devices of his hands.", "darby": "and he shall spread forth his hands in the midst of them, as he that swimmeth spreadeth them forth to swim; and he shall bring down their pride together with the plots of their hands.", "twenty": "", "jps": "And when he shall spread forth his hands in the midst thereof, as he that swimmeth spreadeth forth his hands to swim, his pride shall be brought down together with the cunning of his hands.", "acv": "And he shall spread forth his hands in the midst of it as he who swims spreads forth his hands to swim. But Jehovah will lay low his pride together with the craft of his hands.", "anderson": "", "haweis": "", "noyes": "And he shall stretch out his hands in the midst of it, As the swimmer stretcheth out his hands to swim, But God shall put down his pride, Together with the devices of his hands.", "webster": "And he will spread forth his hands in the midst of them, as he that swimmeth spreadeth forth [his hands] to swim: and he will bring down their pride together with the spoils of their hands.", "vulgate": "et extendet manus suas sub eo sicut extendit natans ad natandum et humiliabit gloriam eius cum adlisione manuum eius;", "brenton": "And he shall spread forth his hands, even as he also brings down man to destroy him: and he shall bring low his pride in regard to the thing on which he has laid his hands."}}, {"v": 12, "ref": "25:12", "o": "וּ/מִבְצַ֞ר מִשְׂגַּ֣ב חוֹמֹתֶ֗י/ךָ הֵשַׁ֥ח הִשְׁפִּ֛יל הִגִּ֥יעַ לָ/אָ֖רֶץ עַד עָפָֽר", "en": {"kjv": "And the fortress of the high fort of thy walls shall he bring down, lay low, and bring to the ground, even to the dust.", "web": "He has brought the high fortress of your walls down, laid low, and brought to the ground, even to the dust.", "bsb": "The high-walled fortress will be brought down, cast to the ground, into the dust.", "asv": "And the high fortress of thy walls hath he brought down, laid low, and brought to the ground, even to the dust.", "ylt": "And the fortress of the high place of thy walls He hath bowed down--He hath made low, He hath caused it to come to the earth, --unto dust.", "dra": "And the bulwarks of thy high walls shall fall, and be brought low, and shall be pulled down to the ground, even to the dust.", "bbe": "And the strong tower of your walls has been broken by him, made low, and crushed even to the dust.", "geneva": "The defence also of the height of thy walles shall he bring downe and lay lowe, and cast them to the ground, euen vnto the dust.", "wycliffe": "And the strengthingis of thin hiy wallis schulen falle doun, and schulen be maad low, and schulen be drawun doun to the erthe, `til to the dust.", "rotherham": "Yea, the lofty stronghold of thy walls, Hath he brought down—Laid low—Levelled to the ground even unto the dust.", "darby": "And the fortress of the high defences of thy walls will he bring down, lay low, bring to the ground, into the dust.", "twenty": "", "jps": "And the high fortress of thy walls will He bring down, lay low, and bring to the ground, even to the dust.", "acv": "And the high fortress of thy walls he has brought down, laid low, and brought to the ground, even to the dust.", "anderson": "", "haweis": "", "noyes": "And the high bulwarks of thy walls will he lay low; He will bring them down to the ground; he will lay them in the dust.", "webster": "And the fortress of the high fort of thy walls will he bring down, lay low, [and] bring to the ground, [even] to the dust.", "vulgate": "et munimenta sublimium murorum tuorum concident et humiliabuntur et detrahentur in terram usque ad pulverem;", "brenton": "And he shall bring down the height of the refuge of the wall, and it shall come down even to the ground."}}]}, {"c": 26, "verses": [{"v": 1, "ref": "26:1", "o": "בַּ/יּ֣וֹם הַ/ה֔וּא יוּשַׁ֥ר הַ/שִּׁיר הַ/זֶּ֖ה בְּ/אֶ֣רֶץ יְהוּדָ֑ה עִ֣יר עָז לָ֔/נוּ יְשׁוּעָ֥ה יָשִׁ֖ית חוֹמ֥וֹת וָ/חֵֽל", "en": {"kjv": "In that day shall this song be sung in the land of Judah; We have a strong city; salvation will God appoint for walls and bulwarks.", "web": "In that day, this song will be sung in the land of Judah: “We have a strong city. God appoints salvation for walls and bulwarks.", "bsb": "In that day this song will be sung in the land of Judah: We have a strong city; salvation is established as its walls and ramparts.", "asv": "In that day shall this song be sung in the land of Judah: We have a strong city; salvation will he appoint for walls and bulwarks.", "ylt": "In that day sung is this song in the land of Judah: `We have a strong city, Salvation He doth make walls and bulwark.", "dra": "In that day shall this canticle be sung in the land of Juda. Sion the city of our strength a saviour, a wall and a bulwark shall be set therein.", "bbe": "In that day will this song be made in the land of Judah: We have a strong town; he will make salvation our walls and towers.", "geneva": "In that day shall this song be sung in the land of Iudah, We haue a strong citie: saluation shall God set for walles and bulwarkes.", "wycliffe": "In that dai this song schal be sungun in the lond of Juda. The citee of oure strengthe; the sauyour schal be set ther ynne, the wal and the `fore wal.", "rotherham": "In that day, shall be sung this song, in the land of Judah,—A strong city, have we! Salvation, will he set for walls and rampart,", "darby": "In that day shall this song be sung in the land of Judah: We have a strong city; salvation doth he appoint for walls and bulwarks.", "twenty": "", "jps": "In that day shall this song be sung in the land of Judah: We have a strong city; walls and bulwarks doth He appoint for salvation.", "acv": "In that day this song shall be sung in the land of Judah: We have a strong city. He will appoint salvation for walls and bulwarks.", "anderson": "", "haweis": "", "noyes": "In that day shall this song be sung in the land of Judah: \"We have a strong city; His aid doth God appoint for walls and bulwarks.", "webster": "In that day shall this song be sung in the land of Judah; We have a strong city; salvation will [God] appoint [for] walls and bulwarks.", "vulgate": "in die illa cantabitur canticum istud in terra Iuda urbs fortitudinis nostrae salvator ponetur in ea murus et antemurale;", "brenton": "In that day they shall sing this song in the land of Judea; Behold a strong city; and he shall make salvation its wall and bulwark."}}, {"v": 2, "ref": "26:2", "o": "פִּתְח֖וּ שְׁעָרִ֑ים וְ/יָבֹ֥א גוֹי צַדִּ֖יק שֹׁמֵ֥ר אֱמֻנִֽים", "en": {"kjv": "Open ye the gates, that the righteous nation which keepeth the truth may enter in.", "web": "Open the gates, that the righteous nation may enter: the one which keeps faith.", "bsb": "Open the gates so a righteous nation may enter— one that remains faithful.", "asv": "Open ye the gates, that the righteous nation which keepeth faith may enter in.", "ylt": "Open ye the gates, that enter may a righteous nation, Preserving stedfastness.", "dra": "Open ye the gates, and let the just nation, that keepeth the truth, enter in.", "bbe": "Let the doors be open, so that the upright nation which keeps faith may come in.", "geneva": "Open ye the gates that the righteous nation, which keepeth the trueth, may enter in.", "wycliffe": "Opene ye the yatis, and the iust folk schal entre, kepynge treuthe.", "rotherham": "Open ye the gates,—That there may enter in—a righteous nation preserving fidelity.", "darby": "Open ye the gates, and the righteous nation which keepeth faithfulness shall enter in.", "twenty": "", "jps": "Open ye the gates, that the righteous nation that keepeth faithfulness may enter in.", "acv": "Open ye the gates, that the righteous nation which keeps faith may enter in.", "anderson": "", "haweis": "", "noyes": "Open ye the gates, That the righteous nation may enter in, The nation that keepeth the truth.", "webster": "Open ye the gates, that the righteous nation which keepeth the truth may enter in.", "vulgate": "aperite portas et ingrediatur gens iusta custodiens veritatem;", "brenton": "Open ye the gates, let the nation enter that keeps righteousness, and keeps truth,"}}, {"v": 3, "ref": "26:3", "o": "יֵ֣צֶר סָמ֔וּךְ תִּצֹּ֖ר שָׁל֣וֹם שָׁל֑וֹם כִּ֥י בְ/ךָ֖ בָּטֽוּחַ", "en": {"kjv": "Thou wilt keep him in perfect peace, whose mind is stayed on thee: because he trusteth in thee.", "web": "You will keep whoever’s mind is steadfast in perfect peace, because he trusts in you.", "bsb": "You will keep in perfect peace the steadfast of mind, because he trusts in You.", "asv": "Thou wilt keep him in perfect peace, whose mind is stayed on thee; because he trusteth in thee.", "ylt": "An imagination supported Thou fortifiest peace--peace! For in Thee it is confident.", "dra": "The old error is passed away: thou wilt keep peace: peace, because we have hoped in thee.", "bbe": "The man whose heart is unmoved you will keep in peace, because his hope is in you.", "geneva": "By an assured purpose wilt thou preserue perfite peace, because they trusted in thee.", "wycliffe": "The elde errour is gon awei; thou schalt kepe pees, pees, for thou, Lord, we hopiden in thee.", "rotherham": "A purpose sustained, thou wilt guard, [saying], Prosper! Prosper! Because in thee, hath he been led to trust.", "darby": "Thou wilt keep in perfect peace the mind stayed [on thee], for he confideth in thee.", "twenty": "", "jps": "The mind stayed on Thee Thou keepest in perfect peace; because it trusteth in Thee.", "acv": "Thou will keep him in perfect peace, whose mind is stayed on thee, because he trusts in thee.", "anderson": "", "haweis": "", "noyes": "Him that is of a steadfast mind Thou wilt keep in continual peace, Because he trusteth in thee.", "webster": "Thou wilt keep [him] in perfect peace, [whose] mind [is] stayed [on thee]: because he trusteth in thee.", "vulgate": "vetus error abiit servabis pacem pacem quia in te speravimus;", "brenton": "supporting truth, and keeping peace: for on thee, O Lord,"}}, {"v": 4, "ref": "26:4", "o": "בִּטְח֥וּ בַֽ/יהוָ֖ה עֲדֵי עַ֑ד כִּ֚י בְּ/יָ֣הּ יְהוָ֔ה צ֖וּר עוֹלָמִֽים", "en": {"kjv": "Trust ye in the Lord for ever: for in the Lord Jehovah is everlasting strength:", "web": "Trust in Yahweh forever; for in Yah, Yahweh, is an everlasting Rock.", "bsb": "Trust in the LORD forever, because GOD the LORD is the Rock eternal.", "asv": "Trust ye in Jehovah for ever; for in Jehovah, even Jehovah, is an everlasting rock.", "ylt": "Trust ye in Jehovah for ever, For in Jah Jehovah is a rock of ages,", "dra": "You have hoped in the Lord for evermore, in the Lord God mighty for ever.", "bbe": "Let your hope be in the Lord for ever: for the Lord Jah is an unchanging Rock.", "geneva": "Trust in the Lord for euer: for in the Lord God is strength for euermore.", "wycliffe": "Ye han hopid in the Lord, in euerlastynge worldis, in the Lord God, strong with outen ende.", "rotherham": "Trust ye in Yahweh, unto futurity,—For, in Yah, Yahweh, is a rock of ages.", "darby": "Confide ye in Jehovah for ever; for in Jah, Jehovah, is the rock of ages.", "twenty": "", "jps": "Trust ye in HaShem for ever, for HaShem is GOD, an everlasting Rock.", "acv": "Trust ye in Jehovah forever, for in Jehovah, even Jehovah, is an everlasting rock.", "anderson": "", "haweis": "", "noyes": "Trust ye in Jehovah forever, For the Lord Jehovah is an everlasting rock.", "webster": "Trust ye in the LORD for ever: for in the LORD JEHOVAH [is] everlasting strength:", "vulgate": "sperastis in Domino in saeculis aeternis in Domino Deo forti in perpetuum;", "brenton": "they have trusted with confidence for ever, the great, the eternal God;"}}, {"v": 5, "ref": "26:5", "o": "כִּ֤י הֵשַׁח֙ יֹשְׁבֵ֣י מָר֔וֹם קִרְיָ֖ה נִשְׂגָּבָ֑ה יַשְׁפִּילֶ֤/נָּה יַשְׁפִּילָ/הּ֙ עַד אֶ֔רֶץ יַגִּיעֶ֖/נָּה עַד עָפָֽר", "en": {"kjv": "For he bringeth down them that dwell on high; the lofty city, he layeth it low; he layeth it low, even to the ground; he bringeth it even to the dust.", "web": "For he has brought down those who dwell on high, the lofty city. He lays it low. He lays it low even to the ground. He brings it even to the dust.", "bsb": "For He has humbled those who dwell on high; He lays the lofty city low. He brings it down to the ground; He casts it into the dust.", "asv": "For he hath brought down them that dwell on high, the lofty city: he layeth it low, he layeth it low even to the ground; he bringeth it even to the dust.", "ylt": "For He bowed down the dwellers on high, A city set on high He maketh low, He maketh it low unto the earth, He causeth it to come unto the dust,", "dra": "For he shall bring down them that dwell on high, the high city he shall lay low. He shall bring it down even to the ground, he shall pull it down even to the dust.", "bbe": "For he has made low those who are lifted up, all the people of the town of pride: he makes it low, crushing it down to the earth; he makes it low in the dust.", "geneva": "For hee will bring downe them that dwell on hie: the hie citie he will abase: euen vnto the ground wil he cast it downe, and bring it vnto dust.", "wycliffe": "For he schal bowe doun hem that dwellen an hiy, and he schal make low an hiy citee; he schal make it low `til to the erthe; he schal drawe it doun `til to the dust.", "rotherham": "For he hath brought down the inhabitants of the height the city exalted,—He layeth it low, Layeth it low even to the ground, Levelleth it, even to the dust:", "darby": "For he bringeth down them that dwell on high; the lofty city, he layeth it low, he layeth it low to the ground, he bringeth it even to the dust.", "twenty": "", "jps": "For He hath brought down them that dwell on high, the lofty city, laying it low, laying it low even to the ground, bringing it even to the dust.", "acv": "For he has brought down those who dwell on high. The lofty city, he lays it low. He lays it low even to the ground. He brings it even to the dust.", "anderson": "", "haweis": "", "noyes": "For he hath brought down the inhabitants of the fortress; The lofty city he hath laid low; He hath laid her low even to the ground; He hath levelled her with the dust.", "webster": "For he bringeth down them that dwell on high; the lofty city, he layeth it low; he layeth it low, [even] to the ground; he bringeth it [even] to the dust.", "vulgate": "quia incurvabit habitantes in excelso civitatem sublimem humiliabit humiliabit eam usque ad terram detrahet eam usque ad pulverem;", "brenton": "who hast humbled and brought down them that dwell on high, thou shalt cast down strong cities, and bring them to the ground."}}, {"v": 6, "ref": "26:6", "o": "תִּרְמְסֶ֖/נָּה רָ֑גֶל רַגְלֵ֥י עָנִ֖י פַּעֲמֵ֥י דַלִּֽים", "en": {"kjv": "The foot shall tread it down, even the feet of the poor, and the steps of the needy.", "web": "The foot shall tread it down; Even the feet of the poor, and the steps of the needy.”", "bsb": "Feet trample it down— the feet of the oppressed, the steps of the poor.", "asv": "The foot shall tread it down; even the feet of the poor, and the steps of the needy.", "ylt": "Tread it down doth a foot, Feet of the poor--steps of the weak.", "dra": "The foot shall tread it down, the feet of the poor, the steps of the needy.", "bbe": "It will be crushed under the feet of the poor and the steps of those who are in need.", "geneva": "The foote shall treade it downe, euen the feete of the poore, and the steppes of the needie.", "wycliffe": "The foot of a pore man schal defoule it, and the steppis of nedi men schulen defoule it.", "rotherham": "The foot trampleth it,—The feet of the lowly, The steps of the weak,", "darby": "The foot shall tread it down, — the feet of the afflicted, the steps of the poor.", "twenty": "", "jps": "The foot shall tread it down, even the feet of the poor, and the steps of the needy.", "acv": "The foot shall tread it down, even the feet of the poor, and the steps of the needy.", "anderson": "", "haweis": "", "noyes": "The foot trampleth upon her, The feet of the poor, the steps of the needy.", "webster": "The foot shall tread it down, [even] the feet of the poor, [and] the steps of the needy.", "vulgate": "conculcabit eam pes pedes pauperis gressus egenorum;", "brenton": "And the feet of the meek and lowly shall trample them."}}, {"v": 7, "ref": "26:7", "o": "אֹ֥רַח לַ/צַּדִּ֖יק מֵֽישָׁרִ֑ים יָשָׁ֕ר מַעְגַּ֥ל צַדִּ֖יק תְּפַלֵּֽס", "en": {"kjv": "The way of the just is uprightness: thou, most upright, dost weigh the path of the just.", "web": "The way of the just is uprightness. You who are upright make the path of the righteous level.", "bsb": "The path of the righteous is level; You clear a straight path for the upright.", "asv": "The way of the just is uprightness: thou that art upright dost direct the path of the just.", "ylt": "The path for the righteous is uprightness, O upright One, The path of the righteous Thou dost ponder.", "dra": "The way of the just is right, the path of the just is right to walk in.", "bbe": "The way of the good man is straight; the road of the upright is made smooth by you.", "geneva": "The way of the iust is righteousnesse: thou wilt make equall the righteous path of the iust.", "wycliffe": "The weie of a iust man is riytful, the path of a iust man is riytful to go.", "rotherham": "The path of a righteous man, is, even,—O Upright One! the track of a righteous man, thou makest level.", "darby": "The way of the just is uprightness: thou, the Upright, dost make the path of the just even.", "twenty": "", "jps": "The way of the just is straight; Thou, Most Upright, makest plain the path of the just.", "acv": "The way of the just is uprightness. Thou who are upright directs the path of the just.", "anderson": "", "haweis": "", "noyes": "The way of the upright is a smooth way; Thou, O most righteous, doth level the path of the upright!", "webster": "The way of the just [is] uprightness: thou, most upright, dost weigh the path of the just.", "vulgate": "semita iusti recta est rectus callis iusti ad ambulandum;", "brenton": "The way of the godly is made straight: the way of the godly is also prepared."}}, {"v": 8, "ref": "26:8", "o": "אַ֣ף אֹ֧רַח מִשְׁפָּטֶ֛י/ךָ יְהוָ֖ה קִוִּינ֑וּ/ךָ לְ/שִׁמְ/ךָ֥ וּֽ/לְ/זִכְרְ/ךָ֖ תַּאֲוַת נָֽפֶשׁ", "en": {"kjv": "Yea, in the way of thy judgments, O Lord, have we waited for thee; the desire of our soul is to thy name, and to the remembrance of thee.", "web": "Yes, in the way of your judgments, Yahweh, have we waited for you. Your name and your renown are the desire of our soul.", "bsb": "Yes, we wait for You, O LORD; we walk in the path of Your judgments. Your name and renown are the desire of our souls.", "asv": "Yea, in the way of thy judgments, O Jehovah, have we waited for thee; to thy name, even to thy memorial name, is the desire of our soul.", "ylt": "Also, in the path of Thy judgments, O Jehovah, we have waited for Thee, To Thy name and to Thy remembrance Is the desire of the soul.", "dra": "And in the way of thy judgments, O Lord, we have patiently waited for thee: thy name, and thy remembrance are the desire of the soul.", "bbe": "We have been waiting for you, O Lord; the desire of our soul is for the memory of your name.", "geneva": "Also we, O Lord, haue waited for thee in the way of thy iudgemets: the desire of our soule is to thy Name, and to the remembrance of thee.", "wycliffe": "And in the weie of thi domes, Lord, we suffriden thee; thi name, and thi memorial is in desir of soule.", "rotherham": "Surely in the path of thy regulations, O Yahweh, we waited for thee,—Unto thy Name and unto thy Memorial, was there a longing of soul:", "darby": "Yea, in the way of thy judgments, O Jehovah, have we waited for thee; the desire of [our] soul is to thy name, and to thy memorial.", "twenty": "", "jps": "Yea, in the way of Thy judgments, O HaShem, have we waited for Thee; to Thy name and to Thy memorial is the desire of our soul.", "acv": "Yea, in the way of thy judgments, O Jehovah, we have waited for thee, to thy name. Even to thy memorial, is the desire of our soul.", "anderson": "", "haweis": "", "noyes": "In the way of thy judgments, O Jehovah, we have waited for thee; The desire of our souls is to thy name, and to the remembrance of thee.", "webster": "Yes, in the way of thy judgments, O LORD, have we waited for thee; the desire of [our] soul [is] to thy name, and to the remembrance of thee.", "vulgate": "et in semita iudiciorum tuorum Domine sustinuimus te nomen tuum et memoriale tuum in desiderio animae;", "brenton": "For the way of the Lord is judgment: we have hoped in thy name, and on the remembrance of thee,"}}, {"v": 9, "ref": "26:9", "o": "נַפְשִׁ֤/י אִוִּיתִ֨י/ךָ֙ בַּ/לַּ֔יְלָה אַף רוּחִ֥/י בְ/קִרְבִּ֖/י אֲשַֽׁחֲרֶ֑/ךָּ כִּ֞י כַּ/אֲשֶׁ֤ר מִשְׁפָּטֶ֨י/ךָ֙ לָ/אָ֔רֶץ צֶ֥דֶק לָמְד֖וּ יֹשְׁבֵ֥י תֵבֵֽל", "en": {"kjv": "With my soul have I desired thee in the night; yea, with my spirit within me will I seek thee early: for when thy judgments are in the earth, the inhabitants of the world will learn righteousness.", "web": "With my soul have I desired you in the night. Yes, with my spirit within me will I seek you earnestly; for when your judgments are in the earth, the inhabitants of the world learn righteousness.", "bsb": "My soul longs for You in the night; indeed, my spirit seeks You at dawn. For when Your judgments come upon the earth, the people of the world learn righteousness.", "asv": "With my soul have I desired thee in the night; yea, with my spirit within me will I seek thee earnestly: for when thy judgments are in the earth, the inhabitants of the world learn righteousness.", "ylt": "With my soul I desired Thee in the night, Also, with my spirit within me I seek Thee earnestly, For when Thy judgments are on the earth, The inhabitants of the world have learned righteousness.", "dra": "My soul hath desired thee in the night: yea, and with my spirit within me in the morning early I will watch to thee. When thou shalt do thy judgments on the earth, the inhabitants of the world shall learn justice.", "bbe": "In the night the desire of my soul has been for you; early will my spirit be searching for you; for when your punishments come on the earth, the people of the world will get the knowledge of righteousness.", "geneva": "With my soule haue I desired thee in the night, and with my spirit within mee will I seeke thee in the morning: for seeing thy iudgements are in the earth, the inhabitants of the world shall learne righteousnesse.", "wycliffe": "My soule schal desire thee in the niyt, but also with my spirit in myn entrails; fro the morewtid Y schal wake to thee. Whanne thou schalt make thi domes in erthe, alle dwelleris of the world schulen lerne riytfulnesse.", "rotherham": "With my soul, longed I for thee in the night, Yea with my spirit within me, I kept on searching for thee,—For, when thy regulations [extend] to the earth, The inhabitants of the world will have learned, righteousness.", "darby": "With my soul have I desired thee in the night; yea, with my spirit within me I seek thee early: for when thy judgments are in the earth, the inhabitants of the world learn righteousness.", "twenty": "", "jps": "With my soul have I desired Thee in the night; yea, with my spirit within me have I sought Thee earnestly; for when Thy judgments are in the earth, the inhabitants of the world learn righteousness.", "acv": "With my soul I have desired thee in the night. Yea, with my spirit within me I will seek thee earnestly. For when thy judgments are in the earth, the inhabitants of the world learn righteousness.", "anderson": "", "haweis": "", "noyes": "My soul longeth for thee in the night, And my spirit within me seeketh thee in the morning; For when thy judgments are in the earth, The inhabitants of the world learn righteousness.", "webster": "With my soul have I desired thee in the night; yes, with my spirit within me will I seek thee early: for when thy judgments [are] in the earth, the inhabitants of the world will learn righteousness.", "vulgate": "anima mea desideravit te in nocte sed et spiritu meo in praecordiis meis de mane vigilabo ad te cum feceris iudicia tua in terra iustitiam discent habitatores orbis;", "brenton": "which our soul longs for: my spirit seeks thee very early in the morning, O God, for thy commandments are a light on the earth: learn righteousness, ye that dwell upon the earth."}}, {"v": 10, "ref": "26:10", "o": "יֻחַ֤ן רָשָׁע֙ בַּל לָמַ֣ד צֶ֔דֶק בְּ/אֶ֥רֶץ נְכֹח֖וֹת יְעַוֵּ֑ל וּ/בַל יִרְאֶ֖ה גֵּא֥וּת יְהוָֽה", "en": {"kjv": "Let favour be shewed to the wicked, yet will he not learn righteousness: in the land of uprightness will he deal unjustly, and will not behold the majesty of the Lord.", "web": "Let favor be shown to the wicked, yet he will not learn righteousness. In the land of uprightness he will deal wrongfully, and will not see Yahweh’s majesty.", "bsb": "Though grace is shown to the wicked man, he does not learn righteousness. In the land of righteousness he acts unjustly and fails to see the majesty of the LORD.", "asv": "Let favor be showed to the wicked, yet will he not learn righteousness; in the land of uprightness will he deal wrongfully, and will not behold the majesty of Jehovah.", "ylt": "The wicked findeth favour, He hath not learned righteousness, In a land of straightforwardness he dealeth perversely, And seeth not the excellency of Jehovah.", "dra": "Let us have pity on the wicked, but he will not learn justice: in the land of the saints he hath done wicked things, and he shall not see the glory of the Lord.", "bbe": "Even if you are kind to the evil-doer, he will not go after righteousness; even in the land of the upright he will still go on in his wrongdoing, and will not see the glory of the Lord.", "geneva": "Let mercie bee shewed to the wicked, yet hee will not learne righteousnesse: in the land of vprightnesse will he do wickedly, and will not beholde the maiestie of the Lord.", "wycliffe": "Do we merci to the wickid man, and he schal not lerne to do riytfulnesse; in the lond of seyntis he dide wickid thingis, and he schal not se the glorie of the Lord.", "rotherham": "Let favour be shewed to the lawless, he hath not learned righteousness, In a land of honest dealings, he acteth perversely,—And seeth not the splendour of Yahweh.", "darby": "If favour be shewn to the wicked, he doth not learn righteousness: in the land of uprightness he dealeth unjustly, and beholdeth not the majesty of Jehovah.", "twenty": "", "jps": "Let favour be shown to the wicked, yet will he not learn righteousness; in the land of uprightness will he deal wrongfully, and will not behold the majesty of HaShem.", "acv": "Let favor be shown to a wicked man, yet he will not learn righteousness. In the land of uprightness he will deal wrongfully, and will not behold the majesty of Jehovah.", "anderson": "", "haweis": "", "noyes": "Though favor be shown to the wicked, He will not learn righteousness; In the land of uprightness will he deal unjustly, And have no regard to the majesty of Jehovah.", "webster": "Let favor be shown to the wicked, [yet] he will not learn righteousness: in the land of uprightness he will deal unjustly, and will not behold the majesty of the LORD.", "vulgate": "misereamur impio et non discet iustitiam in terra sanctorum inique gessit et non videbit gloriam Domini;", "brenton": "For the ungodly one is put down: no one who will not learn righteousness on the earth, shall be able to do the truth: let the ungodly be taken away, that he see not the glory of the Lord."}}, {"v": 11, "ref": "26:11", "o": "יְהוָ֛ה רָ֥מָה יָדְ/ךָ֖ בַּל יֶחֱזָי֑וּ/ן יֶחֱז֤וּ וְ/יֵבֹ֨שׁוּ֙ קִנְאַת עָ֔ם אַף אֵ֖שׁ צָרֶ֥י/ךָ תֹאכְלֵֽ/ם", "en": {"kjv": "Lord, when thy hand is lifted up, they will not see: but they shall see, and be ashamed for their envy at the people; yea, the fire of thine enemies shall devour them.", "web": "Yahweh, your hand is lifted up, yet they don’t see; but they will see your zeal for the people, and be disappointed. Yes, fire will consume your adversaries.", "bsb": "O LORD, Your hand is upraised, but they do not see it. They will see Your zeal for Your people and be put to shame. The fire set for Your enemies will consume them!", "asv": "Jehovah, thy hand is lifted up, yet they see not: but they shall seethyzeal for the people, and be put to shame; yea, fire shall devour thine adversaries.", "ylt": "O Jehovah, high is Thy hand--they see not, They see the zeal of the people, and are ashamed, Also, the fire--Thine adversaries, consumeth them.", "dra": "Lord, let thy hand be exalted, and let them not see: let the envious people see, and be confounded: and let fire devour thy enemies.", "bbe": "Lord, your hand is lifted up, but they do not see: let them see ... yes, your haters will be burned up in the fire.", "geneva": "O Lord, they will not beholde thine hie hande: but they shall see it, and bee confounded with the zeale of the people, and the fire of thine enemies shall deuoure them.", "wycliffe": "Lord, thin hond be enhaunsid, that thei se not; puplis hauynge enuye se, and be schent, and fier deuoure thin enemyes.", "rotherham": "O Yahweh though thy hand be lifted up,—yet do they not see, Would they might see—and turn pale at a people’s zeal,—Surely, the fire of thine enemies, must consume them!", "darby": "Jehovah, thy hand is lifted up, but they do not see: [yet] they shall see [thy] jealousy [for] the people, and be ashamed; yea, the fire which is for thine adversaries shall devour them.", "twenty": "", "jps": "HaShem, Thy hand was lifted up, yet they see not; they shall see with shame Thy zeal for the people; yea, fire shall devour Thine adversaries.", "acv": "Jehovah, thy hand is lifted up, yet they do not see. But they shall see thy zeal for the people, and be put to shame. Yea, fire shall devour thine adversaries.", "anderson": "", "haweis": "", "noyes": "Thy hand, O Jehovah, is lifted up, yet do they not see; But they shall see with shame thy zeal for thy people; Yea, fire shall devour thine adversaries.", "webster": "LORD, [when] thy hand is lifted up, they will not see: [but] they shall see, and be ashamed for [their] envy at the people; yes, the fire of thy enemies shall devour them.", "vulgate": "Domine exaltetur manus tua et non videant videant et confundantur zelantes populi et ignis hostes tuos devoret;", "brenton": "O Lord, thine arm is exalted, yet they knew it not: but when they know they shall be ashamed: jealousy shall seize upon an untaught nation, and now fire shall devour the adversaries."}}, {"v": 12, "ref": "26:12", "o": "יְהוָ֕ה תִּשְׁפֹּ֥ת שָׁל֖וֹם לָ֑/נוּ כִּ֛י גַּ֥ם כָּֽל מַעֲשֵׂ֖י/נוּ פָּעַ֥לְתָּ לָּֽ/נוּ", "en": {"kjv": "Lord, thou wilt ordain peace for us: for thou also hast wrought all our works in us.", "web": "Yahweh, you will ordain peace for us, for you have also worked all our works for us.", "bsb": "O LORD, You will establish peace for us. For all that we have accomplished, You have done for us.", "asv": "Jehovah, thou wilt ordain peace for us; for thou hast also wrought all our works for us.", "ylt": "O Jehovah, Thou appointest peace to us, For, all our works also Thou hast wrought for us.", "dra": "Lord, thou wilt give us peace: for thou hast wrought all our works for us.", "bbe": "Lord, you will give us peace: for all our works are the outcome of your purpose.", "geneva": "Lord, vnto vs thou wilt ordeine peace: for thou also hast wrought all our workes for vs.", "wycliffe": "Lord, thou schalt yyue pees to vs, for thou hast wrouyt alle oure werkis in vs.", "rotherham": "O Yahweh, thou wilt ensure prosperity for us,—For even all our works, hast thou wrought for us,", "darby": "Jehovah, thou wilt ordain peace for us; for thou also hast wrought all our works for us.", "twenty": "", "jps": "HaShem, Thou wilt establish peace for us; for Thou hast indeed wrought all our works for us.", "acv": "Jehovah, thou will ordain peace for us, for thou have also wrought all our works for us.", "anderson": "", "haweis": "", "noyes": "Thou, O Jehovah, wilt give us peace; For all our works thou doest for us.", "webster": "LORD, thou wilt ordain peace for us: for thou also hast wrought all our works in us.", "vulgate": "Domine dabis pacem nobis omnia enim opera nostra operatus es nobis;", "brenton": "O Lord our God, give us peace: for thou hast rendered to us all things."}}, {"v": 13, "ref": "26:13", "o": "יְהוָ֣ה אֱלֹהֵ֔י/נוּ בְּעָל֥וּ/נוּ אֲדֹנִ֖ים זֽוּלָתֶ֑/ךָ לְ/בַד בְּ/ךָ֖ נַזְכִּ֥יר שְׁמֶֽ/ךָ", "en": {"kjv": "O Lord our God, other lords beside thee have had dominion over us: but by thee only will we make mention of thy name.", "web": "Yahweh our God, other lords besides you have had dominion over us, but by you only will we make mention of your name.", "bsb": "O LORD our God, other lords besides You have had dominion, but Your name alone do we confess.", "asv": "O Jehovah our God, other lords besides thee have had dominion over us; but by thee only will we make mention of thy name.", "ylt": "O Jehovah our God, lords have ruled us besides Thee, Only, by Thee we make mention of Thy name.", "dra": "O Lord our God, other lords besides thee have had dominion over us, only in thee let us remember thy name.", "bbe": "O Lord, our God, other lords than you have had rule over us; but in you only is our salvation, and no other name will we take on our lips.", "geneva": "O Lord our God, other lords beside thee, haue ruled vs, but we will remember thee onely, and thy Name.", "wycliffe": "Oure Lord God, lordis hadden vs in possessioun, withouten thee; oneli in thee haue we mynde of thi name.", "rotherham": "O Yahweh, our God! Lords other than thee, have owned us,—By thyself alone, will we call upon thy Name.", "darby": "Jehovah ourGod, other lords than thee have had dominion over us; by thee only will we make mention of thy name.", "twenty": "", "jps": "O HaShem our G-d, other lords beside Thee have had dominion over us; but by Thee only do we make mention of Thy name.", "acv": "O Jehovah our God, other lords besides thee have had dominion over us, but by thee only we will make mention of thy name.", "anderson": "", "haweis": "", "noyes": "O Jehovah, our God, other lords have had dominion over us besides thee; Only through thee do we call upon thy name.", "webster": "O LORD our God, [other] lords beside thee have had dominion over us; [but] by thee only will we make mention of thy name.", "vulgate": "Domine Deus noster possederunt nos domini absque te tantum in te recordemur nominis tui;", "brenton": "O Lord our God, take possession of us: O Lord, we know not any other beside thee: we name thy name."}}, {"v": 14, "ref": "26:14", "o": "מֵתִים֙ בַּל יִחְי֔וּ רְפָאִ֖ים בַּל יָקֻ֑מוּ לָ/כֵ֤ן פָּקַ֨דְתָּ֙ וַ/תַּשְׁמִידֵ֔/ם וַ/תְּאַבֵּ֥ד כָּל זֵ֖כֶר לָֽ/מוֹ", "en": {"kjv": "They are dead, they shall not live; they are deceased, they shall not rise: therefore hast thou visited and destroyed them, and made all their memory to perish.", "web": "The dead shall not live. The departed spirits shall not rise. Therefore you have visited and destroyed them, and caused all memory of them to perish.", "bsb": "The dead will not live; the departed spirits will not rise. Therefore You have punished and destroyed them; You have wiped out all memory of them.", "asv": "They are dead, they shall not live; they are deceased, they shall not rise: therefore hast thou visited and destroyed them, and made all remembrance of them to perish.", "ylt": "Dead--they live not, Rephaim, they rise not, Therefore Thou hast inspected and dost destroy them, Yea, thou destroyest all their memory.", "dra": "Let not the dead live, let not the giants rise again: therefore hast visited and destroyed them, and hast destroyed all their memory.", "bbe": "The dead will not come back to life: their spirits will not come back to earth; for this cause you have sent destruction on them, so that the memory of them is dead.", "geneva": "The dead shall not liue, neither shall the dead arise, because thou hast visited and scattered them, and destroyed all their memorie.", "wycliffe": "Thei that dien, lyue not, and giauntis risen not ayen. Therfor thou hast visityd, and hast al-to broke hem, and thou hast lost al the mynde of hem; and Lord, thou hast foryoue to a folc,", "rotherham": "The dead, come not to life again, The shades, do not arise,—Therefore, thou hast visited and destroyed them, And caused to perish every memorial of them.", "darby": "[They are] dead, they shall not live; deceased, they shall not rise: for thou hast visited and destroyed them, and made all memory of them to perish.", "twenty": "", "jps": "The dead live not, the shades rise not; to that end hast Thou punished and destroyed them, and made all their memory to perish.", "acv": "Being dead, they shall not live. Being deceased, they shall not rise. Therefore thou have visited and destroyed them, and made all remembrance of them to perish.", "anderson": "", "haweis": "", "noyes": "They are dead, they shall not live; They are shades, they shall not rise. For thou hast visited and destroyed them, And caused all the memory of them to perish.", "webster": "[They are] dead, they shall not live; [they are] deceased, they shall not rise: therefore hast thou visited and destroyed them, and made all their memory to perish.", "vulgate": "morientes non vivant gigantes non resurgant propterea visitasti et contrivisti eos et perdidisti omnem memoriam eorum;", "brenton": "But the dead shall not see life, neither shall physicians by any means raise them up: therefore thou hast brought wrath upon them, and slain them, and hast taken away every male of them. Bring more evils upon them, O Lord;"}}, {"v": 15, "ref": "26:15", "o": "יָסַ֤פְתָּ לַ/גּוֹי֙ יְהוָ֔ה יָסַ֥פְתָּ לַ/גּ֖וֹי נִכְבָּ֑דְתָּ רִחַ֖קְתָּ כָּל קַצְוֵי אָֽרֶץ", "en": {"kjv": "Thou hast increased the nation, O Lord, thou hast increased the nation: thou art glorified: thou hadst removed it far unto all the ends of the earth.", "web": "You have increased the nation, O Yahweh. You have increased the nation! You are glorified! You have enlarged all the borders of the land.", "bsb": "You have enlarged the nation, O LORD; You have enlarged the nation. You have gained glory for Yourself; You have extended all the borders of the land.", "asv": "Thou hast increased the nation, O Jehovah, thou hast increased the nation; thou art glorified; thou hast enlarged all the borders of the land.", "ylt": "Thou hast added to the nation, O Jehovah, Thou hast added to the nation, Thou hast been honoured, Thou hast put far off all the ends of earth.", "dra": "Thou hast been favourable to the nation, O Lord, thou hast been favourable to the nation: art thou glorified? thou hast removed all the ends of the earth far off.", "bbe": "You have made the nation great, O Lord, you have made it great; glory is yours: you have made wide the limits of the land.", "geneva": "Thou hast increased the nation, O Lord: thou hast increased the nation: thou art made glorious: thou hast enlarged all the coastes of the earth.", "wycliffe": "thou hast foryoue to a folc. Whether thou art glorified? thou hast maad fer fro thee all the endis of erthe.", "rotherham": "Thou hast increased the nation, O Yahweh, Thou hast increased the nation thou hast gotten thyself glory, Thou hast extended far, all the ends of the land.", "darby": "Thou hast increased the nation, Jehovah, thou hast increased the nation: thou art glorified. Thou hadst removed [it] far [unto] all the ends of the earth.", "twenty": "", "jps": "Thou hast gotten Thee honour with the nations, O HaShem, yea, exceeding great honour with the nations; Thou art honoured unto the farthest ends of the earth.", "acv": "Thou have increased the nation, O Jehovah, thou have increased the nation. Thou are glorified. Thou have enlarged all the borders of the land.", "anderson": "", "haweis": "", "noyes": "\"Thou wilt enlarge the nation, O Jehovah! Thou wilt enlarge the nation; thou wilt glorify thyself; Thou wilt widely extend all the borders of the land.", "webster": "Thou hast increased the nation, O LORD, thou hast increased the nation; thou art glorified: thou hadst removed [it] far to all the ends of the earth.", "vulgate": "indulsisti genti Domine indulsisti genti numquid glorificatus es elongasti omnes terminos terrae;", "brenton": "bring more evils on the glorious ones of the earth."}}, {"v": 16, "ref": "26:16", "o": "יְהוָ֖ה בַּ/צַּ֣ר פְּקָד֑וּ/ךָ צָק֣וּ/ן לַ֔חַשׁ מוּסָרְ/ךָ֖ לָֽ/מוֹ", "en": {"kjv": "Lord, in trouble have they visited thee, they poured out a prayer when thy chastening was upon them.", "web": "Yahweh, in trouble they have visited you. They poured out a prayer when your chastening was on them.", "bsb": "O LORD, they sought You in their distress; when You disciplined them, they poured out a quiet prayer.", "asv": "Jehovah, in trouble have they visited thee; they poured out a prayer when thy chastening was upon them.", "ylt": "O Jehovah, in distress they missed Thee, They have poured out a whisper, Thy chastisement is on them.", "dra": "Lord, they have sought after thee in distress, in the tribulation of murmuring thy instruction was with them.", "bbe": "Lord, in trouble our eyes have been turned to you, we sent up a prayer when your punishment was on us.", "geneva": "Lord, in trouble haue they visited thee: they powred out a prayer when thy chastening was vpon them.", "wycliffe": "Lord, in angwisch thei souyten thee; in the tribulacioun of grutchyng thi doctryn to hem.", "rotherham": "O Yahweh! in distress, they sought thee,—They poured out a whispered prayer, when thy chastening was upon them.", "darby": "Jehovah, in trouble they sought thee; they poured out [their] whispered prayer when thy chastening was upon them.", "twenty": "", "jps": "HaShem, in trouble have they sought Thee, silently they poured out a prayer when Thy chastening was upon them.", "acv": "Jehovah, in trouble they have visited thee, they poured out a prayer when thy chastening was upon them.", "anderson": "", "haweis": "", "noyes": "O Jehovah, in affliction they sought thee; They poured out their prayer, when thy chastisement was upon them.", "webster": "LORD, in trouble have they visited thee, they poured out a prayer [when] thy chastening [was] upon them.", "vulgate": "Domine in angustia requisierunt te in tribulatione murmuris doctrina tua eis;", "brenton": "Lord, in affliction I remembered thee; thy chastening was to us with small affliction."}}, {"v": 17, "ref": "26:17", "o": "כְּמ֤וֹ הָרָה֙ תַּקְרִ֣יב לָ/לֶ֔דֶת תָּחִ֥יל תִּזְעַ֖ק בַּ/חֲבָלֶ֑י/הָ כֵּ֛ן הָיִ֥ינוּ מִ/פָּנֶ֖י/ךָ יְהוָֽה", "en": {"kjv": "Like as a woman with child, that draweth near the time of her delivery, is in pain, and crieth out in her pangs; so have we been in thy sight, O Lord.", "web": "Like as a woman with child, who draws near the time of her delivery, is in pain and cries out in her pangs; so we have been before you, Yahweh.", "bsb": "As a woman with child about to give birth writhes and cries out in pain, so were we in Your presence, O LORD.", "asv": "Like as a woman with child, that draweth near the time of her delivery, is in pain and crieth out in her pangs; so we have been before thee, O Jehovah.", "ylt": "When a pregnant woman cometh near to the birth, She is pained--she crieth in her pangs, So we have been from Thy face, O Jehovah.", "dra": "As a woman with child, when she draweth near the time of her delivery, is in pain, and crieth out in her pangs: so are we become in thy presence, O Lord.", "bbe": "As a woman with child, whose time is near, is troubled, crying out in her pain; so have we been before you, O Lord.", "geneva": "Like as a woman with childe, that draweth neere to the trauaile, is in sorow, and cryeth in her paines, so haue we bene in thy sight, O Lord.", "wycliffe": "As sche that conseyuede, whanne sche neiyeth sorewful to the child beryng, crieth in her sorewis, so we ben maad, Lord, of thi face.", "rotherham": "Like as a woman with child—Draweth near to giving birth, Is in pain, Crieth out in her pangs So, were we before thee, O Yahweh;—", "darby": "As a woman with child, that draweth near her delivery, is in travail, [and] crieth out in her pangs; so have we been before thee, Jehovah.", "twenty": "", "jps": "Like as a woman with child, that draweth near the time of her delivery, is in pain and crieth out in her pangs; so have we been at Thy presence, O HaShem.", "acv": "As a woman with child, who draws near the time of her delivery, is in pain and cries out in her pangs, so we have been before thee, O Jehovah.", "anderson": "", "haweis": "", "noyes": "As a woman with child, when her delivery is near, Is in anguish, and crieth aloud in her pangs, So have we been, far from thy presence, O Jehovah!", "webster": "As a woman with child, [that] draweth near the time of her delivery, is in pain, [and] crieth out in her pangs; so have we been in thy sight, O LORD.", "vulgate": "sicut quae concipit cum adpropinquaverit ad partum dolens clamat in doloribus suis sic facti sumus a facie tua Domine;", "brenton": "And as a woman in travail draws nigh to be delivered, and cries out in her pain; so have we been to thy beloved."}}, {"v": 18, "ref": "26:18", "o": "הָרִ֣ינוּ חַ֔לְנוּ כְּמ֖וֹ יָלַ֣דְנוּ ר֑וּחַ יְשׁוּעֹת֙ בַּל נַ֣עֲשֶׂה אֶ֔רֶץ וּ/בַֽל יִפְּל֖וּ יֹשְׁבֵ֥י תֵבֵֽל", "en": {"kjv": "We have been with child, we have been in pain, we have as it were brought forth wind; we have not wrought any deliverance in the earth; neither have the inhabitants of the world fallen.", "web": "We have been with child. We have been in pain. We gave birth, it seems, only to wind. We have not worked any deliverance in the earth; neither have the inhabitants of the world fallen.", "bsb": "We were with child; we writhed in pain; but we gave birth to wind. We have given no salvation to the earth, nor brought any life into the world.", "asv": "We have been with child, we have been in pain, we have as it were brought forth wind; we have not wrought any deliverance in the earth; neither have the inhabitants of the world fallen.", "ylt": "We have conceived, we have been pained. We have brought forth as it were wind, Salvation we do not work in the earth, Nor do the inhabitants of the world fall.", "dra": "We have conceived, and been as it were in labour, and have brought forth wind: we have not wrought salvation on the earth, therefore the inhabitants of the earth have not fallen.", "bbe": "We have been with child, we have been in pain, we have given birth to wind; no salvation has come to the earth through us, and no children have come into the world.", "geneva": "We haue coceiued, we haue borne in paine, as though we should haue brought forth winde: there was no helpe in the earth, neither did the inhabitants of the world fall.", "wycliffe": "We han conseyued, and we han as trauelid of child, and we han childid the spirit of helthe; we diden not riytfulnesse in erthe. Therfor the dwelleris of erthe fellen not doun; thi deed men schulen lyue,", "rotherham": "We were with child—We were in pain, As it were we brought forth wind,—Salvation, we could not accomplish for the earth, Neither were born the inhabitants of the world.", "darby": "We have been with child, we have been in travail, we have as it were brought forth wind; we have not wrought the deliverance of the land, neither have the inhabitants of the world fallen.", "twenty": "", "jps": "We have been with child, we have been in pain, we have as it were brought forth wind; we have not wrought any deliverance in the land; neither are the inhabitants of the world come to life.", "acv": "We have been with child. We have been in pain. We have as it were brought forth wind. We have not wrought any deliverance in the earth, nor have the inhabitants of the world fallen.", "anderson": "", "haweis": "", "noyes": "We have been with child; we have been in anguish, Yet have, as it were, brought forth wind. To the land we bring no deliverance; Nor are the inhabitants of the land born.", "webster": "We have been with child, we have been in pain, we have as it were brought forth wind; we have not wrought any deliverance on the earth; neither have the inhabitants of the world fallen.", "vulgate": "concepimus et quasi parturivimus et peperimus spiritum salutes non fecimus in terra ideo non ceciderunt habitatores terrae;", "brenton": "We have conceived, O Lord, because of thy fear, and have been in pain, and have brought forth the breath of thy salvation, which we have wrought upon the earth: we shall not fall, but all that dwell upon the land shall fall."}}, {"v": 19, "ref": "26:19", "o": "יִֽחְי֣וּ מֵתֶ֔י/ךָ נְבֵלָתִ֖/י יְקוּמ֑וּ/ן הָקִ֨יצוּ וְ/רַנְּנ֜וּ שֹׁכְנֵ֣י עָפָ֗ר כִּ֣י טַ֤ל אוֹרֹת֙ טַלֶּ֔/ךָ וָ/אָ֖רֶץ רְפָאִ֥ים תַּפִּֽיל", "en": {"kjv": "Thy dead men shall live, together with my dead body shall they arise. Awake and sing, ye that dwell in dust: for thy dew is as the dew of herbs, and the earth shall cast out the dead.", "web": "Your dead shall live. My dead bodies shall arise. Awake and sing, you who dwell in the dust; for your dew is like the dew of herbs, and the earth will cast out the departed spirits.", "bsb": "Your dead will live; their bodies will rise. Awake and sing, you who dwell in the dust! For your dew is like the dew of the morning, and the earth will bring forth her dead.", "asv": "Thy dead shall live; my dead bodies shall arise. Awake and sing, ye that dwell in the dust; for thy dew is as the dew of herbs, and the earth shall cast forth the dead.", "ylt": "`Thy dead live--My dead body they rise. Awake and sing, ye dwellers in the dust, For the dew of herbs is thy dew, And the land of Rephaim thou causest to fall.", "dra": "Thy dead men shall live, my slain shall rise again: awake, and give praise, ye that dwell in the dust: for thy dew is the dew of the light: and the land of the giants thou shalt pull down into ruin.", "bbe": "Your dead will come back; their dead bodies will come to life again. Those in the dust, awaking from their sleep, will send out a song; for your dew is a dew of light, and the earth will give birth to the shades.", "geneva": "Thy dead men shall liue: euen with my body shall they rise. Awake, and sing, ye that dwel in dust: for thy dewe is as the dew of herbes, and the earth shall cast out the dead.", "wycliffe": "and my slayn men schulen rise ayen. Ye that dwellen in dust, awake, and herie; for whi the deew of liyt is thi deew, and thou schalt drawe doun the lond of giauntis in to fallyng.", "rotherham": "Thy dead, shall come to life again, My dead body, they shall arise,—Awake and shout for joy, ye that dwell in the dust For, a dew of light, is thy dew, And, earth, to the shades shall give birth.", "darby": "Thy dead shall live, my dead bodies shall arise. Awake and sing in triumph, ye that dwell in dust; for thy dew is the dew of the morning, and the earth shall cast forth the dead.", "twenty": "", "jps": "Thy dead shall live, my dead bodies shall arise--awake and sing, ye that dwell in the dust--for Thy dew is as the dew of light, and the earth shall bring to life the shades.", "acv": "Thy dead shall live. My dead bodies shall arise. Awake and sing, ye who dwell in the dust, for thy dew is as the dew of herbs, and the earth shall cast forth the dead.", "anderson": "", "haweis": "", "noyes": "O might thy dead live again, Might the dead bodies of my people arise! Awake, and sing, ye that dwell in the dust! For thy dew is like the dew upon plants, And the earth shall bring forth her dead.\"", "webster": "Thy dead [men] shall live, [together with] my dead body shall they arise. Awake and sing, ye that dwell in dust: for thy dew [is as] the dew of herbs, and the earth shall cast out the dead.", "vulgate": "vivent mortui tui interfecti mei resurgent expergiscimini et laudate qui habitatis in pulvere quia ros lucis ros tuus et terram gigantum detrahes in ruinam;", "brenton": "The dead shall rise, and they that are in the tombs shall be raised, and they that are in the earth shall rejoice: for the dew from thee is healing to them: but the land of the ungodly shall perish."}}, {"v": 20, "ref": "26:20", "o": "לֵ֤ךְ עַמִּ/י֙ בֹּ֣א בַ/חֲדָרֶ֔י/ךָ וּֽ/סְגֹ֥ר דלתי/ך דְּלָתְ/ךָ֖ בַּעֲדֶ֑/ךָ חֲבִ֥י כִ/מְעַט רֶ֖גַע עַד יעבור יַעֲבָר זָֽעַם", "en": {"kjv": "Come, my people, enter thou into thy chambers, and shut thy doors about thee: hide thyself as it were for a little moment, until the indignation be overpast.", "web": "Come, my people, enter into your rooms, and shut your doors behind you. Hide yourself for a little moment, until the indignation is past.", "bsb": "Go, my people, enter your rooms and shut your doors behind you. Hide yourselves a little while until the wrath has passed.", "asv": "Come, my people, enter thou into thy chambers, and shut thy doors about thee: hide thyself for a little moment, until the indignation be overpast.", "ylt": "Come, My people, enter into thy inner chambers, And shut thy doors behind thee, Hide thyself shortly a moment till the indignation pass over.", "dra": "Go, my people, enter into thy chambers, shut thy doors upon thee, hide thyself a little for a moment, until the indignation pass away.", "bbe": "Come, my people, into your secret places, and let your doors be shut: keep yourself safe for a short time, till his wrath is over.", "geneva": "Come, my people: enter thou into thy chambers, and shut thy doores after thee: hide thy selfe for a very litle while, vntill the indignation passe ouer.", "wycliffe": "Go thou, my puple, entre in to thi beddis, close thi doris on thee, be thou hid a litil at a moment, til indignacioun passe.", "rotherham": "Come my people, enter into thy chambers, And shut thy doors behind thee,—Hide thee as it were a little moment Till the indignation pass over.", "darby": "Come, my people, enter into thy chambers, and shut thy doors about thee; hide thyself just for a little moment, until the indignation be past.", "twenty": "", "jps": "Come, my people, enter thou into thy chambers, and shut thy doors about thee; hide thyself for a little moment, until the indignation be overpast.", "acv": "Come, my people, enter thou into thy chambers, and shut thy doors around thee. Hide thyself for a little moment until the indignation be passed over.", "anderson": "", "haweis": "", "noyes": "Come, my people, enter into thy chambers, And shut thy doors behind thee; Hide thyself for a little moment, Until the indignation be overpast!", "webster": "Come, my people, enter thou into thy chambers, and shut thy doors about thee; hide thyself as it were for a little moment until the indignation shall be overpast.", "vulgate": "vade populus meus intra in cubicula tua claude ostia tua super te abscondere modicum ad momentum donec pertranseat indignatio;", "brenton": "Go, my people, enter into thy closets, shut thy door, hide thyself for a little season, until the anger of the Lord have passed away."}}, {"v": 21, "ref": "26:21", "o": "כִּֽי הִנֵּ֤ה יְהוָה֙ יֹצֵ֣א מִ/מְּקוֹמ֔/וֹ לִ/פְקֹ֛ד עֲוֺ֥ן יֹֽשֵׁב הָ/אָ֖רֶץ עָלָ֑י/ו וְ/גִלְּתָ֤ה הָ/אָ֨רֶץ֙ אֶת דָּמֶ֔י/הָ וְ/לֹֽא תְכַסֶּ֥ה ע֖וֹד עַל הֲרוּגֶֽי/הָ", "en": {"kjv": "For, behold, the Lord cometh out of his place to punish the inhabitants of the earth for their iniquity: the earth also shall disclose her blood, and shall no more cover her slain.", "web": "For, behold, Yahweh comes out of his place to punish the inhabitants of the earth for their iniquity. The earth also will disclose her blood, and will no longer cover her slain.", "bsb": "For behold, the LORD is coming out of His dwelling to punish the inhabitants of the earth for their iniquity. The earth will reveal her bloodshed and will no longer conceal her slain.", "asv": "For, behold, Jehovah cometh forth out of his place to punish the inhabitants of the earth for their iniquity: the earth also shall disclose her blood, and shall no more cover her slain.", "ylt": "For, lo, Jehovah is coming out of His place, To charge the iniquity of the inhabitant of the earth upon him, And revealed hath the earth her blood, Nor doth she cover any more her slain!'", "dra": "For behold the Lord will come out of his place, to visit the iniquity of the inhabitant of the earth against him: and the earth shall disclose her blood, and shall cover her slain no more.", "bbe": "For the Lord is coming out of his place to send punishment on the people of the earth for their evil-doing: the earth will let the blood drained out on her be seen, and will keep her dead covered no longer.", "geneva": "For lo, the Lord commeth out of his place, to visite the iniquitie of the inhabitants of the earth vpon them: and the earth shall disclose her blood, and shall no more hide her slaine.", "wycliffe": "For lo! the Lord schal go out of his place, to visite the wickidnesse of the dwellere of erthe ayens hym; and the erthe schal schewe his blood, and schal no more hile hise slayn men.", "rotherham": "For lo! Yahweh, is coming forth out of his place, To visit the iniquity of earth’s inhabitant upon him,—Therefore shall the earth unveil her shed-blood, And throw a covering, no longer over her slain.", "darby": "For behold, Jehovah cometh out of his place to visit the iniquity of the inhabitants of the earth upon them; and the earth shall disclose her blood, and shall no more cover her slain.", "twenty": "", "jps": "For, behold, HaShem cometh forth out of His place to visit upon the inhabitants of the earth their iniquity; the earth also shall disclose her blood, and shall no more cover her slain.", "acv": "For, behold, Jehovah comes forth out of his place to punish the inhabitants of the earth for their iniquity. The earth also shall disclose her blood, and shall no more cover her slain.", "anderson": "", "haweis": "", "noyes": "For behold, Jehovah cometh forth from his place, To punish the inhabitants of the earth for their iniquity; And the earth shall disclose her blood, And shall no longer cover her slain.", "webster": "For behold, the LORD cometh out of his place to punish the inhabitants of the earth for their iniquity: the earth also shall disclose her blood, and shall no more cover her slain.", "vulgate": "ecce enim Dominus egreditur de loco suo ut visitet iniquitatem habitatoris terrae contra eum et revelabit terra sanguinem suum et non operiet ultra interfectos suos;", "brenton": "For, behold, the Lord is bringing wrath from his holy place upon the dwellers on the earth: the earth also shall disclose her blood, and shall not cover her slain."}}]}, {"c": 27, "verses": [{"v": 1, "ref": "27:1", "o": "בַּ/יּ֣וֹם הַ/ה֡וּא יִפְקֹ֣ד יְהוָה֩ בְּ/חַרְב֨/וֹ הַ/קָּשָׁ֜ה וְ/הַ/גְּדוֹלָ֣ה וְ/הַֽ/חֲזָקָ֗ה עַ֤ל לִוְיָתָן֙ נָחָ֣שׁ בָּרִ֔חַ וְ/עַל֙ לִוְיָתָ֔ן נָחָ֖שׁ עֲקַלָּת֑וֹן וְ/הָרַ֥ג אֶת הַ/תַּנִּ֖ין אֲשֶׁ֥ר בַּ/יָּֽם", "en": {"kjv": "In that day the Lord with his sore and great and strong sword shall punish leviathan the piercing serpent, even leviathan that crooked serpent; and he shall slay the dragon that is in the sea.", "web": "In that day, Yahweh with his hard and great and strong sword will punish leviathan, the fleeing serpent, and leviathan the twisted serpent; and he will kill the dragon that is in the sea.", "bsb": "In that day the LORD will take His sharp, great, and mighty sword, and bring judgment on Leviathan the fleeing serpent—Leviathan the coiling serpent—and He will slay the dragon of the sea.", "asv": "In that day Jehovah with his hard and great and strong sword will punish leviathan the swift serpent, and leviathan the crooked serpent; and he will slay the monster that is in the sea.", "ylt": "In that day lay a charge doth Jehovah, With his sword--the sharp, and the great, and the strong, On leviathan--a fleeing serpent, And on leviathan--a crooked serpent, And He hath slain the dragon that is in the sea.", "dra": "In that day the Lord with his hard, and great, and strong sword shall visit leviathan the bar serpent, and leviathan the crooked serpent, and shall slay the whale that is in the sea.", "bbe": "In that day the Lord, with his great and strong and cruel sword, will send punishment on Leviathan, the quick-moving snake, and on Leviathan, the twisted snake; and he will put to death the dragon which is in the sea.", "geneva": "In that day the Lord with his sore and great and mightie sword shall visite Liuiathan, that pearcing serpent, euen Liuiathan, that crooked serpent, and he shall slay the dragon that is in the sea.", "wycliffe": "In that dai the Lord schal visite in his hard swerd, and greet, and strong, on leuyathan, serpent, a barre, and on leuyathan, the crookid serpent; and he schal sle the whal, which is in the see.", "rotherham": "In that day, will Yahweh With his sword—the hard and the great and the strong, Bring punishment Upon Leviathan, the fleeing serpent, And upon Leviathan, the crooked serpent,—And will slay the monster which is in the sea.", "darby": "In that day Jehovah, with his sore and great and strong sword, will visit leviathan the fleeing serpent, and leviathan the crooked serpent; and he will slay the monster that is in the sea.", "twenty": "", "jps": "In that day HaShem with His sore and great and strong sword will punish leviathan the slant serpent, and leviathan the tortuous serpent; and He will slay the dragon that is in the sea.", "acv": "In that day Jehovah with his hard and great and strong sword will punish leviathan the swift serpent, and leviathan the crooked serpent, and he will kill the monster that is in the sea.", "anderson": "", "haweis": "", "noyes": "In that day will Jehovah punish with his sword, His hard, and great, and strong sword, The leviathan, that fleet serpent, Even the leviathan, that winding serpent; Yea, he will slay the monster, that is in the sea.", "webster": "In that day the LORD with his keen and great and strong sword will punish leviathan the piercing serpent, even leviathan that crooked serpent; and he will slay the dragon that [is] in the sea.", "vulgate": "in die illo visitabit Dominus in gladio suo duro et grandi et forti super Leviathan serpentem vectem et super Leviathan serpentem tortuosum et occidet cetum qui in mari est;", "brenton": "In that day God shall bring his holy and great and strong sword upon the dragon, even the serpent that flees, upon the dragon, the crooked serpent: he shall destroy the dragon."}}, {"v": 2, "ref": "27:2", "o": "בַּ/יּ֖וֹם הַ/ה֑וּא כֶּ֥רֶם חֶ֖מֶד עַנּוּ לָֽ/הּ", "en": {"kjv": "In that day sing ye unto her, A vineyard of red wine.", "web": "In that day, sing to her, “A pleasant vineyard!", "bsb": "In that day: “Sing about a fruitful vineyard.", "asv": "In that day: A vineyard of wine, sing ye unto it.", "ylt": "In that day, `A desirable vineyard,' respond ye to her,", "dra": "In that day there shall be singing to the vineyard of pure wine.", "bbe": "In that day it will be said, A vine-garden of delight, make a song about it.", "geneva": "In that daye sing of the vineyarde of redde wine.", "wycliffe": "In that dai the vyner of cleen wyn and good schal synge to him.", "rotherham": "In that day, A Wine-Vineyard! sing ye unto her:", "darby": "In that day [there shall be] a vineyard of pure wine; sing concerning it:", "twenty": "", "jps": "In that day sing ye of her: 'A vineyard of foaming wine!'", "acv": "In that day is a vineyard of wine. Sing ye to it.", "anderson": "", "haweis": "", "noyes": "In that day, sing ye thus concerning the vineyard:", "webster": "In that day sing ye to her, A vineyard of red wine.", "vulgate": "in die illa vinea meri cantabit ei;", "brenton": "In that day there shall be a fair vineyard, and a desire to commence a song concerning it."}}, {"v": 3, "ref": "27:3", "o": "אֲנִ֤י יְהוָה֙ נֹֽצְרָ֔/הּ לִ/רְגָעִ֖ים אַשְׁקֶ֑/נָּה פֶּ֚ן יִפְקֹ֣ד עָלֶ֔י/הָ לַ֥יְלָה וָ/י֖וֹם אֶצֳּרֶֽ/נָּה", "en": {"kjv": "I the Lord do keep it; I will water it every moment: lest any hurt it, I will keep it night and day.", "web": "I, Yahweh, am its keeper. I will water it every moment. Lest anyone damage it, I will keep it night and day.", "bsb": "I, the LORD, am its keeper; I water it continually. I guard it night and day so no one can disturb it;", "asv": "I Jehovah am its keeper; I will water it every moment: lest any hurt it, I will keep it night and day.", "ylt": "I, Jehovah, am its keeper, every moment I water it, Lest any lay a charge against it, Night and day I keep it!", "dra": "I am the Lord that keep it, I will suddenly give it drink: lest any hurt come to it, I keep it night and day.", "bbe": "I, the Lord, am watching it; I will give it water at all times: I will keep it night and day, for fear that any damage comes to it.", "geneva": "I the Lord doe keepe it: I will water it euery moment: least any assaile it, I will keepe it night and day.", "wycliffe": "Y am the Lord that kepe that vyner; sudeynli Y schal yyue drynke to it, lest perauenture it be visitid ayens it;", "rotherham": "I—Yahweh, am Watching over her, Every moment, will I water her,—Lest anyone injure her, Night and day, will I watch over her.", "darby": "I Jehovah keep it, I will water it every moment; lest any harm it, I will keep it night and day.", "twenty": "", "jps": "I HaShem do guard it, I water it every moment; lest Mine anger visit it, I guard it night and day.", "acv": "I Jehovah am its keeper, I will water it every moment. Lest any hurt it, I will guard it night and day.", "anderson": "", "haweis": "", "noyes": "\"I, Jehovah, am its guardian; I will water it every moment; That no one may assault it, I will watch it day and night.", "webster": "I the LORD do keep it; I will water it every moment: lest [any] hurt it, I will keep it night and day.", "vulgate": "ego Dominus qui servo eam repente propinabo ei ne forte visitetur contra eam nocte et die servo eam;", "brenton": "I am a strong city, a city in a siege: in vain shall I water it; for it shall be taken by night, and by day the wall shall fall."}}, {"v": 4, "ref": "27:4", "o": "חֵמָ֖ה אֵ֣ין לִ֑/י מִֽי יִתְּנֵ֜/נִי שָׁמִ֥יר שַׁ֨יִת֙ בַּ/מִּלְחָמָ֔ה אֶפְשְׂעָ֥ה בָ֖/הּ אֲצִיתֶ֥/נָּה יָּֽחַד", "en": {"kjv": "Fury is not in me: who would set the briers and thorns against me in battle? I would go through them, I would burn them together.", "web": "Wrath is not in me, but if I should find briers and thorns, I would do battle! I would march on them and I would burn them together.", "bsb": "I am not angry. If only thorns and briers confronted Me, I would march and trample them, I would burn them to the ground.", "asv": "Wrath is not in me: would that the briers and thorns were against me in battle! I would march upon them, I would burn them together.", "ylt": "Fury is not in Me; Who giveth Me a brier--a thorn in battle? I step into it, I burn it at once.", "dra": "There is no indignation in me: who shall make me a thorn and a brier in battle: shall I march against it, shall, I set it on fire together?", "bbe": "My passion is over: if the thorns were fighting against me, I would make an attack on them, and they would be burned up together.", "geneva": "Anger is not in mee: who would set the briers and the thornes against me in battel? I would go through them, I would burne them together.", "wycliffe": "nyyt and dai Y kepe it, indignacioun is not to me. Who schal yyue me a thorn and brere? In batel Y schal go on it, Y schal brenne it togidere.", "rotherham": "Fury, have I none,—Oh that there were delivered to me briars and thorns, in battle! I would march in among them I would set fire to them one and all.", "darby": "Fury is not in me. Oh that I had briars [and] thorns in battle against me! I would march against them, I would burn them together.", "twenty": "", "jps": "Fury is not in Me; would that I were as the briers and thorns in flame! I would with one step burn it altogether.", "acv": "Wrath is not in me. Would that the briers and thorns were against me in battle! I would march upon them. I would burn them together.", "anderson": "", "haweis": "", "noyes": "There is no fury in me; But let me find the thorns and thistles in battle. I will go against them, And burn them up together,", "webster": "Fury [is] not in me: who would set the briers [and] thorns against me in battle? I would go through them, I would burn them together.", "vulgate": "indignatio non est mihi quis dabit me spinam et veprem in proelio gradiar super eam succendam eam pariter;", "brenton": "There is no woman that has not taken hold of it; who will set me to watch stubble in the field? because of this enemy I have set her aside; therefore on this account the Lord has done all that he appointed."}}, {"v": 5, "ref": "27:5", "o": "א֚וֹ יַחֲזֵ֣ק בְּ/מָעוּזִּ֔/י יַעֲשֶׂ֥ה שָׁל֖וֹם לִ֑/י שָׁל֖וֹם יַֽעֲשֶׂה לִּֽ/י", "en": {"kjv": "Or let him take hold of my strength, that he may make peace with me; and he shall make peace with me.", "web": "Or else let him take hold of my strength, that he may make peace with me. Let him make peace with me.”", "bsb": "Or let them lay claim to My protection; let them make peace with Me— yes, let them make peace with Me.”", "asv": "Or else let him take hold of my strength, that he may make peace with me; yea, let him make peace with me.", "ylt": "Or--he doth take hold on My strength, He doth make peace with Me, Peace he doth make with Me.", "dra": "Or rather shall it take hold of my strength, shall it make peace with me, shall it make peace with me?", "bbe": "Or let him put himself under my power, and make peace with me.", "geneva": "Or will he feele my strength, that he may make peace with me, and be at one with me?", "wycliffe": "Whether rathere Y schal holde my strengthe? It schal make pees to me, it schal make pees to me, for", "rotherham": "Else, let one lay hold of my protection, Let him make peace with me,—Peace, let him make with me.", "darby": "Or let him take hold of my strength; let him make peace with me: [yea,] let him make peace with me.", "twenty": "", "jps": "Or else let him take hold of My strength, that he may make peace with Me; yea, let him make peace with Me.", "acv": "Or else let him take hold of my strength, that he may make peace with me. Yea, let him make peace with me.", "anderson": "", "haweis": "", "noyes": "Unless they take hold of my protection, And with me make peace, And make peace with me.\"", "webster": "Or let him take hold of my strength, [that] he may make peace with me, [and] he shall make peace with me.", "vulgate": "an potius tenebit fortitudinem meam faciet pacem mihi pacem faciet mihi;", "brenton": "I am burnt up; they that dwell in her shall cry, Let us make peace with him, let us make peace,"}}, {"v": 6, "ref": "27:6", "o": "הַ/בָּאִים֙ יַשְׁרֵ֣שׁ יַֽעֲקֹ֔ב יָצִ֥יץ וּ/פָרַ֖ח יִשְׂרָאֵ֑ל וּ/מָלְא֥וּ פְנֵי תֵבֵ֖ל תְּנוּבָֽה", "en": {"kjv": "He shall cause them that come of Jacob to take root: Israel shall blossom and bud, and fill the face of the world with fruit.", "web": "In days to come, Jacob will take root. Israel will blossom and bud. They will fill the surface of the world with fruit.", "bsb": "In the days to come, Jacob will take root. Israel will bud and blossom and fill the whole world with fruit.", "asv": "In days to come shall Jacob take root; Israel shall blossom and bud; and they shall fill the face of the world with fruit.", "ylt": "Those coming in He causeth to take root, Jacob doth blossom, and flourished hath Israel, And they have filled the face of the world with increase.", "dra": "When they shall rush in unto Jacob, Israel shall blossom and bud, and they shall fill the face of the world with seed.", "bbe": "In days to come Jacob will take root: Israel will put out buds and flowers; and the face of the world will be full of fruit.", "geneva": "Hereafter, Iaakob shall take roote: Israel shall florish and growe, and the world shall be filled with fruite.", "wycliffe": "the merit of hem that schulen go out with fersnesse fro Jacob. Israel schal floure and brynge forth seed, and thei schulen fille the face of the world with seed.", "rotherham": "In coming times, shall Jacob strike root, Israel, shall blossom and bud,—Then shall they fill the face of the world with fruit.", "darby": "In the future Jacob shall take root; Israel shall blossom and bud, and they shall fill the face of the world with fruit.", "twenty": "", "jps": "In days to come shall Jacob take root, Israel shall blossom and bud; and the face of the world shall be filled with fruitage.", "acv": "In days to come Jacob shall take root; Israel shall blossom and bud. And they shall fill the face of the world with fruit.", "anderson": "", "haweis": "", "noyes": "In coming days shall Jacob take root, And Israel flourish and bud forth, And fill the world with fruit.", "webster": "He shall cause them that descend from Jacob to take root: Israel shall blossom and bud, and fill the face of the world with fruit.", "vulgate": "qui egrediuntur impetu ad Iacob florebit et germinabit Israhel et implebunt faciem orbis semine;", "brenton": "they that are coming are the children of Jacob. Israel shall bud and blossom, and the world shall be filled with his fruit."}}, {"v": 7, "ref": "27:7", "o": "הַ/כְּ/מַכַּ֥ת מַכֵּ֖/הוּ הִכָּ֑/הוּ אִם כְּ/הֶ֥רֶג הֲרֻגָ֖י/ו הֹרָֽג", "en": {"kjv": "Hath he smitten him, as he smote those that smote him? or is he slain according to the slaughter of them that are slain by him?", "web": "Has he struck them as he struck those who struck them? Or are they killed like those who killed them were killed?", "bsb": "Has the LORD struck Israel as He struck her oppressors? Was she killed like those who slayed her?", "asv": "Hath he smitten them as he smote those that smote them? or are they slain according to the slaughter of them that were slain by them?", "ylt": "As the smiting of his smiter hath He smitten him? As the slaying of his slain doth He slay?", "dra": "Hath he struck him according to the stroke of him that struck him? or is he slain, as he killed them that were slain by him?", "bbe": "Is his punishment like the punishment of those who overcame him? or are his dead as great in number as those he put to the sword?", "geneva": "Hath hee smitten him as hee smote those that smote him? or is hee slaine according to the slaughter of them that were slaine by him?", "wycliffe": "Whether he smoot it bi the wounde of the puple of Jewis smytynge hym? ether as it killide the slayn men of hym, so it was slayn?", "rotherham": "Was it, with the smiting of his smiter, that he smote him? Or as with the slaying of his slayer, was he slain?", "darby": "Hath he smitten him according to the smiting of those that smote him? Is he slain according to the slaughter of those slain by him?", "twenty": "", "jps": "Hath He smitten him as He smote those that smote him? Or is he slain according to the slaughter of them that were slain by Him?", "acv": "Has he smitten them as he smote those who smote them? Or are they slain according to the slaughter of those who were slain by them?", "anderson": "", "haweis": "", "noyes": "Did he smite Israel, as he smote those that smote him? Was he slain as those that slew him?", "webster": "Hath he smitten him, as he smote those that smote him? [or] is he slain according to the slaughter of them that are slain by him?", "vulgate": "numquid iuxta plagam percutientis se percussit eum aut sicut occidit interfectos eius sic occisus est;", "brenton": "Shall he himself be thus smitten, even as he smote? and as he slew, shall he be thus slain?"}}, {"v": 8, "ref": "27:8", "o": "בְּ/סַּאסְּאָ֖ה בְּ/שַׁלְחָ֣/הּ תְּרִיבֶ֑/נָּה הָגָ֛ה בְּ/רוּח֥/וֹ הַ/קָּשָׁ֖ה בְּ/י֥וֹם קָדִֽים", "en": {"kjv": "In measure, when it shooteth forth, thou wilt debate with it: he stayeth his rough wind in the day of the east wind.", "web": "In measure, when you send them away, you contend with them. He has removed them with his rough blast in the day of the east wind.", "bsb": "By warfare and exile You contended with her and removed her with a fierce wind, as on the day the east wind blows.", "asv": "In measure, when thou sendest them away, thou dost contend with them; he hath removed them with his rough blast in the day of the east wind.", "ylt": "In measure, in sending it forth, thou strivest with it, He hath taken away by His sharp wind, In the day of an east wind,", "dra": "In measure against measure, when it shall be cast off, thou shalt judge it. He hath meditated with his severe spirit in the day of heat.", "bbe": "Your anger against her has been made clear by driving her away; he has taken her away with his storm-wind in the day of his east wind.", "geneva": "In measure in the branches thereof wilt thou contende with it, when he bloweth with his rough winde in the day of the East winde.", "wycliffe": "In mesure ayens mesure, whanne it schal be cast awei, he schal deme it; he bithouyte in his hard spirit, bi the dai of heete.", "rotherham": "By driving her away—by dismissing her, wouldest thou contend with her? He removed her by his rough wind in, a day of east wind.", "darby": "In measure, when sending her away, didst thou contend with her: he hath taken [her] away with his rough wind in the day of the east wind.", "twenty": "", "jps": "In full measure, when Thou sendest her away, Thou dost contend with her; He hath removed her with His rough blast in the day of the east wind.", "acv": "In measure, in sending it forth, thou contend with it. He has removed with his rough blast in the day of the east wind.", "anderson": "", "haweis": "", "noyes": "In measure, by sending her away, didst thou punish her, Taking her away in the rough tempest, in the day of the east wind.", "webster": "In measure, when it shooteth forth, thou wilt debate with it: he stayeth his rough wind in the day of the east wind.", "vulgate": "in mensura contra mensuram cum abiecta fuerit iudicabis eam meditata est in spiritu suo duro per diem aestus;", "brenton": "Fighting and reproaching he will dismiss them; didst thou not meditate with a harsh spirit, to slay them with a wrathful spirit?"}}, {"v": 9, "ref": "27:9", "o": "לָ/כֵ֗ן בְּ/זֹאת֙ יְכֻפַּ֣ר עֲוֺֽן יַעֲקֹ֔ב וְ/זֶ֕ה כָּל פְּרִ֖י הָסִ֣ר חַטָּאת֑/וֹ בְּ/שׂוּמ֣/וֹ כָּל אַבְנֵ֣י מִזְבֵּ֗חַ כְּ/אַבְנֵי גִר֙ מְנֻפָּצ֔וֹת לֹֽא יָקֻ֥מוּ אֲשֵׁרִ֖ים וְ/חַמָּנִֽים", "en": {"kjv": "By this therefore shall the iniquity of Jacob be purged; and this is all the fruit to take away his sin; when he maketh all the stones of the altar as chalkstones that are beaten in sunder, the groves and images shall not stand up.", "web": "Therefore by this the iniquity of Jacob will be forgiven, and this is all the fruit of taking away his sin: that he makes all the stones of the altar as chalk stones that are beaten in pieces, so that the Asherah poles and the incense altars shall rise no more.", "bsb": "Therefore Jacob’s guilt will be atoned for, and the full fruit of the removal of his sin will be this: When he makes all the altar stones like crushed bits of chalk, no Asherah poles or incense altars will remain standing.", "asv": "Therefore by this shall the iniquity of Jacob be forgiven, and this is all the fruit of taking away his sin: that he maketh all the stones of the altar as chalkstones that are beaten in sunder, so that the Asherim and the sun-images shall rise no more.", "ylt": "Therefore by this is the iniquity of Jacob covered, And this is all the fruit--To take away his sin, in His setting all the stones of an altar, As chalkstones beaten in pieces, They rise not--shrines and images.", "dra": "Therefore upon this shall the iniquity of the house of Jacob be forgiven: and this is all the fruit, that the sin thereof should be taken away, when he shall have made all the stones of the altar, as burnt stones broken in pieces, the groves and temples shall not stand.", "bbe": "So by this will the sin of Jacob be covered, and this is all the fruit of taking away his punishment; when all the stones of the altar are crushed together, so that the wood pillars and the sun-images will not be put up again.", "geneva": "By this therefore shall the iniquitie of Iaakob be purged, and this is all the fruit, the taking away of his sinne: whe he shall make all the stones of the altars, as chalke stones broken in pieces, that the groues and images may not stand vp.", "wycliffe": "Therfor on this thing wickidnesse schal be foryouun to the hous of Jacob, and this schal be al the fruyt, that the synne therof be don awei, whanne it hath set all the stoonys of the auter as the stoonys of aische hurtlid doun. Wodis and templis schulen not stonde.", "rotherham": "Therefore hereby, shall a propitiatory—covering be put over the iniquity of Jacob, And all, this, is the fruit of taking away his sin,—When he maketh all the stones of an altar like chalk-stones that soon crumble, Sacred Stems and Sun Images, shall not arise.", "darby": "By this, therefore, shall the iniquity of Jacob be purged; and this is all the fruit of the taking away of his sin: when he shall make all the stones of the altar as chalkstones that are crumbled in pieces, — the Asherahs and the sun-images shall not stand.", "twenty": "", "jps": "Therefore by this shall the iniquity of Jacob be expiated, and this is all the fruit of taking away his sin: when he maketh all the stones of the altar as chalkstones that are beaten in pieces, so that the Asherim and the sun-images shall rise no more.", "acv": "Therefore by this the iniquity of Jacob shall be forgiven. And this is all the fruit of taking away his sin: that he makes all the stones of the altar as chalkstones that are beaten apart, so that the Asherim and the sun-images shall rise no more.", "anderson": "", "haweis": "", "noyes": "By this, therefore, is the iniquity of Jacob expiated, And this is wholly the fruit of the removal of his sin, That He has made the stones of the altar like limestones broken in pieces, And that the images of Astarte and the sun-pillars no more stand.", "webster": "By this therefore shall the iniquity of Jacob be purged; and this [is] all the fruit to take away his sin; when he maketh all the stones of the altar as chalk-stones that are beaten asunder, the groves and images shall not stand up.", "vulgate": "idcirco super hoc dimittetur iniquitas domui Iacob et iste omnis fructus ut auferatur peccatum eius cum posuerit omnes lapides altaris sicut lapides cineris adlisos non stabunt luci et delubra;", "brenton": "Therefore shall the iniquity of Jacob be taken away; and this is his blessing, when I shall have taken away his sin; when they shall have broken to pieces all the stones of the altars as fine dust, and their trees shall not remain, and their idols shall be cut off, as a thicket afar off."}}, {"v": 10, "ref": "27:10", "o": "כִּ֣י עִ֤יר בְּצוּרָה֙ בָּדָ֔ד נָוֶ֕ה מְשֻׁלָּ֥ח וְ/נֶעֱזָ֖ב כַּ/מִּדְבָּ֑ר שָׁ֣ם יִרְעֶ֥ה עֵ֛גֶל וְ/שָׁ֥ם יִרְבָּ֖ץ וְ/כִלָּ֥ה סְעִפֶֽי/הָ", "en": {"kjv": "Yet the defenced city shall be desolate, and the habitation forsaken, and left like a wilderness: there shall the calf feed, and there shall he lie down, and consume the branches thereof.", "web": "For the fortified city is solitary, a habitation deserted and forsaken, like the wilderness. The calf will feed there, and there he will lie down, and consume its branches.", "bsb": "For the fortified city lies deserted— a homestead abandoned, a wilderness forsaken. There the calves graze, and there they lie down; they strip its branches bare.", "asv": "For the fortified city is solitary, a habitation deserted and forsaken, like the wilderness: there shall the calf feed, and there shall he lie down, and consume the branches thereof.", "ylt": "For the fenced city is alone, A habitation cast out and forsaken as a wilderness, There doth the calf delight, And there it lieth down, And hath consumed its branches.", "dra": "For the strong city shall be desolate, the beautiful city shall be forsaken, and shall be left as a wilderness: there the calf shall feed, and there shall he lie down, and shall consume its branches.", "bbe": "For the strong town is without men, an unpeopled living-place; and she has become a waste land: there the young ox will take his rest, and its branches will be food for him.", "geneva": "Yet the defenced citie shalbe desolate, and the habitation shalbe forsaken, and left like a wildernes. There shall the calfe feede, and there shall he lie, and consume the branches thereof.", "wycliffe": "Forsothe the strong citee schal be desolat, the fair citee schal be left, and schal be forsakun as a desert; there a calf schal be lesewid, and schal ligge there, and schal waste the hiynessis therof.", "rotherham": "For the fortified city, is solitary, The dwelling forsaken and left as a wilderness,—There, shall the calf feed, And, there, lie down And shall consume the branches thereof:", "darby": "For the fortified city is solitary, a habitation abandoned and forsaken like a wilderness; there shall the calf feed, and there shall he lie down, and consume its boughs.", "twenty": "", "jps": "For the fortified city is solitary, a habitation abandoned and forsaken, like the wilderness; there shall the calf feed, and there shall he lie down, and consume the branches thereof", "acv": "For the fortified city is solitary, a habitation deserted and forsaken like the wilderness. There the calf shall feed, and there he shall lie down, and consume the branches of it.", "anderson": "", "haweis": "", "noyes": "For the fortified city is desolate, A habitation forsaken, deserted like a wilderness; There doth the calf feed, and there doth he lie down, And consume her branches.", "webster": "Yet the fortified city [shall be] desolate, [and] the habitation forsaken, and left like a wilderness: there shall the calf feed, and there shall he lie down, and consume its branches.", "vulgate": "civitas enim munita desolata erit speciosa relinquetur et dimittetur quasi desertum ibi pascetur vitulus et ibi accubabit et consumet summitates eius;", "brenton": "The flock that dwelt there shall be left, as a deserted flock; and the ground shall be for a long time for pasture, and there shall flocks lie down to rest."}}, {"v": 11, "ref": "27:11", "o": "בִּ/יבֹ֤שׁ קְצִירָ/הּ֙ תִּשָּׁבַ֔רְנָה נָשִׁ֕ים בָּא֖וֹת מְאִיר֣וֹת אוֹתָ֑/הּ כִּ֣י לֹ֤א עַם בִּינוֹת֙ ה֔וּא עַל כֵּן֙ לֹֽא יְרַחֲמֶ֣/נּוּ עֹשֵׂ֔/הוּ וְ/יֹצְר֖/וֹ לֹ֥א יְחֻנֶּֽ/נּוּ", "en": {"kjv": "When the boughs thereof are withered, they shall be broken off: the women come, and set them on fire: for it is a people of no understanding: therefore he that made them will not have mercy on them, and he that formed them will shew them no favour.", "web": "When its boughs are withered, they will be broken off. The women will come and set them on fire, for they are a people of no understanding. Therefore he who made them will not have compassion on them, and he who formed them will show them no favor.", "bsb": "When its limbs are dry, they are broken off. Women come and use them for kindling; for this is a people without understanding. Therefore their Maker has no compassion on them, and their Creator shows them no favor.", "asv": "When the boughs thereof are withered, they shall be broken off; the women shall come, and set them on fire; for it is a people of no understanding: therefore he that made them will not have compassion upon them, and he that formed them will show them no favor.", "ylt": "In the withering of its branch it is broken off, Women are coming in setting it on fire, For it is not a people of understanding, Therefore pity it not doth its Maker, And its Former doth not favour it.", "dra": "Its harvest shall be destroyed with drought, women shall come and teach it: for it is not a wise people, therefore he that made it, shall not have mercy on it: and he that formed it, shall not spare it.", "bbe": "When its branches are dry they will be broken off; the women will come and put fire to them: for it is a foolish people; for this cause he who made them will have no mercy on them, and he whose work they are will not have pity on them.", "geneva": "When the boughes of it are drie, they shalbe broken: the women come, and set them on fire: for it is a people of none vnderstading: therefore hee that made them, shall not haue compassion of them, and he that formed them, shall haue no mercie on them.", "wycliffe": "In the drynesse of ripe corn therof wymmen comynge, and thei that techen it, schulen be al to-brokun. Forsothe it is not a wijs puple, therfor he that made it, schal not haue mercy on it; and he that formyde it, schal not spare it.", "rotherham": "When the cut-off boughs thereof are dry, they shall be broken to pieces, Women, coming, are kindling it! For it is not a people of understanding, For this cause, Will he that made him, not have compassion upon him, And, he that formed him, will shew him no favour.", "darby": "When its branches are withered they shall be broken off; women shall come [and] set them on fire. For it is a people of no intelligence; therefore he that made them will not have mercy on them, and he who formed them will shew them no favour.", "twenty": "", "jps": "When the boughs thereof are withered, they shall be broken off; the women shall come, and set them on fire; for it is a people of no understanding; therefore He that made them will not have compassion upon them, and He that formed them will not be gracious unto them.", "acv": "When the boughs of it are withered, they shall be broken off. The women shall come, and set them on fire, for it is a people of no understanding. Therefore he who made them will not have compassion upon them, and he who formed them will show them no favor.", "anderson": "", "haweis": "", "noyes": "When her boughs are withered, they are broken off; Women come, and burn them; For it was a people of no understanding; Therefore he that made him had not mercy on him, And he that formed him showed him no favor.", "webster": "When its boughs are withered, they shall be broken off: the women come [and] set them on fire: for it [is] a people of no understanding: therefore he that made them will not have mercy on them, and he that formed them will show them no favor.", "vulgate": "in siccitate messis illius conterentur mulieres venientes et docentes eam non est enim populus sapiens propterea non miserebitur eius qui fecit eum et qui formavit eum non parcet ei;", "brenton": "And after a time there shall be in it no green thing because of the grass being parched. Come hither, ye women that come from a sight; for it is a people of no understanding; therefore he that made them shall have no pity upon them, and he that formed them shall have no mercy upon them."}}, {"v": 12, "ref": "27:12", "o": "וְ/הָיָה֙ בַּ/יּ֣וֹם הַ/ה֔וּא יַחְבֹּ֧ט יְהוָ֛ה מִ/שִּׁבֹּ֥לֶת הַ/נָּהָ֖ר עַד נַ֣חַל מִצְרָ֑יִם וְ/אַתֶּ֧ם תְּלֻקְּט֛וּ לְ/אַחַ֥ד אֶחָ֖ד בְּנֵ֥י יִשְׂרָאֵֽל", "en": {"kjv": "And it shall come to pass in that day, that the Lord shall beat off from the channel of the river unto the stream of Egypt, and ye shall be gathered one by one, O ye children of Israel.", "web": "It will happen in that day, that Yahweh will thresh from the flowing stream of the Euphrates to the brook of Egypt; and you will be gathered one by one, children of Israel.", "bsb": "In that day the LORD will thresh from the flowing Euphrates to the Wadi of Egypt, and you, O Israelites, will be gathered one by one.", "asv": "And it shall come to pass in that day, that Jehovah will beat off his fruit from the flood of the River unto the brook of Egypt; and ye shall be gathered one by one, O ye children of Israel.", "ylt": "And it hath come to pass, in that day, Beat out doth Jehovah from the branch of the river, Unto the stream of Egypt, And ye are gathered one by one, O sons of Israel.", "dra": "And it shall come to pass, that in that day the Lord will strike from the channel of the river even to the torrent of Egypt, and you shall be gathered together one by one, O ye children of Israel.", "bbe": "And it will be in that day that the Lord will get together his grain, from the River to the stream of Egypt, and you will be got together with care, O children of Israel.", "geneva": "And in that day shall the Lord thresh from the chanell of the Riuer vnto the riuer of Egypt, and ye shalbe gathered, one by one, O children of Israel.", "wycliffe": "And it schal be, in that dai the Lord schal smyte thee, fro the botme of the flood `til to the stronde of Egipt; and ye sones of Israel, schulen be gaderid oon and oon.", "rotherham": "And it shall come to pass, in that day, That Yahweh will beat off his fruit from the stream of the River [=\"Euphrates\"], unto the torrent-valley of Egypt,—And, ye, shall be picked up, one by one O sons of Israel.", "darby": "And it shall come to pass in that day, that Jehovah shall beat out from the flood of the river unto the torrent of Egypt, and ye shall be gathered one by one, [ye] children of Israel.", "twenty": "", "jps": "And it shall come to pass in that day, that HaShem will beat off His fruit from the flood of the River unto the Brook of Egypt, and ye shall be gathered one by one, O ye children of Israel.", "acv": "And it shall come to pass in that day, that Jehovah will beat off his fruit, from the flood of the River to the brook of Egypt. And ye shall be gathered one by one, O ye sons of Israel.", "anderson": "", "haweis": "", "noyes": "But it shall come to pass in that day, That Jehovah shall gather fruit From the stream of the Euphrates to the river of Egypt, And ye shall be gathered, one by one, ye children of Israel!", "webster": "And it shall come to pass in that day, [that] the LORD shall gather from the channel of the river to the stream of Egypt, and ye shall be gathered one by one, O ye children of Israel.", "vulgate": "et erit in die illa percutiet Dominus ab alveo Fluminis usque ad torrentem Aegypti et vos congregabimini unus et unus filii Israhel;", "brenton": "And it shall come to pass in that day that God shall fence men off from the channel of the river as far as Rhinocorura; but do ye gather one by one the children of Israel."}}, {"v": 13, "ref": "27:13", "o": "וְ/הָיָ֣ה בַּ/יּ֣וֹם הַ/ה֗וּא יִתָּקַע֮ בְּ/שׁוֹפָ֣ר גָּדוֹל֒ וּ/בָ֗אוּ הָ/אֹֽבְדִים֙ בְּ/אֶ֣רֶץ אַשּׁ֔וּר וְ/הַ/נִּדָּחִ֖ים בְּ/אֶ֣רֶץ מִצְרָ֑יִם וְ/הִשְׁתַּחֲו֧וּ לַ/יהוָ֛ה בְּ/הַ֥ר הַ/קֹּ֖דֶשׁ בִּ/ירוּשָׁלִָֽם", "en": {"kjv": "And it shall come to pass in that day, that the great trumpet shall be blown, and they shall come which were ready to perish in the land of Assyria, and the outcasts in the land of Egypt, and shall worship the Lord in the holy mount at Jerusalem.", "web": "It will happen in that day that a great trumpet will be blown; and those who were ready to perish in the land of Assyria, and those who were outcasts in the land of Egypt, shall come; and they will worship Yahweh in the holy mountain at Jerusalem.", "bsb": "And in that day a great ram’s horn will sound, and those who were perishing in Assyria will come forth with those who were exiles in Egypt. And they will worship the LORD on the holy mountain in Jerusalem.", "asv": "And it shall come to pass in that day, that a great trumpet shall be blown; and they shall come that were ready to perish in the land of Assyria, and they that were outcasts in the land of Egypt; and they shall worship Jehovah in the holy mountain at Jerusalem.", "ylt": "And it hath come to pass, in that day, It is blown with a great trumpet, And come in have those perishing in the land of Asshur, And those cast out in the land of Egypt, And have bowed themselves to Jehovah, In the holy mount--in Jerusalem!", "dra": "And it shall come to pass, that in that day a noise shall be made with a great trumpet, and they that were lost, shall come from the land of the Assyrians, and they that were outcasts in the land of Egypt, and they shall adore the Lord in the holy mount in Jerusalem.", "bbe": "And it will be in that day that a great horn will be sounded; and those who were wandering in the land of Assyria, and those who had been sent away into the land of Egypt, will come; and they will give worship to the Lord in the holy mountain at Jerusalem.", "geneva": "In that day also shall the great trumpet be blowen, and they shall come, which perished in the land of Asshur: and they that were chased into the lande of Egypt, and they shall worship the Lord in the holy Mount at Ierusalem.", "wycliffe": "And it schal be, in that dai me schal come with a greet trumpe, and thei that weren lost, schulen come fro the lond of Assiriens, and thei that weren cast out, schulen come fro the lond of Egipt; and they schulen worschipe the Lord, in the hooli hil in Jerusalem.", "rotherham": "And it shall come to pass in that day, That there shall be a blowing with a great horn, Then shall come in Such as have wandered in the land of Assyria, And such as have been outcasts in the land of Egypt,—And they shall bow themselves down unto Yahweh In the holy mountain, In Jerusalem.", "darby": "And it shall come to pass in that day, [that] the great trumpet shall be blown; and they shall come that were perishing in the land of Assyria, and the outcasts in the land of Egypt, and they shall worship Jehovah in the holy mountain at Jerusalem.", "twenty": "", "jps": "And it shall come to pass in that day, that a great horn shall be blown; and they shall come that were lost in the land of Assyria, and they that were dispersed in the land of Egypt; and they shall worship HaShem in the holy mountain at Jerusalem.", "acv": "And it shall come to pass in that day, that a great trumpet shall be blown. And they shall come who were ready to perish in the land of Assyria, and those who were outcasts in the land of Egypt. And they shall worship Jehovah in the holy mountain at Jerusalem.", "anderson": "", "haweis": "", "noyes": "In that day shall a great trumpet be sounded, And they shall come who are lost in the land of Assyria, And are outcasts in the land of Egypt, And shall worship Jehovah upon the holy mountain in Jerusalem.", "webster": "And it shall come to pass in that day, [that] the great trumpet shall be blown, and they shall come who were ready to perish in the land of Assyria, and the outcasts in the land of Egypt, and shall worship the LORD on the holy mount at Jerusalem.", "vulgate": "et erit in die illa clangetur in tuba magna et venient qui perditi fuerant de terra Assyriorum et qui eiecti erant in terra Aegypti et adorabunt Dominum in monte sancto in Hierusalem;", "brenton": "And it shall come to pass in that day that they shall blow the great trumpet, and the lost ones in the land of the Assyrians shall come, and the lost ones in Egypt, and shall worship the Lord on the holy mountain in Jerusalem."}}]}, {"c": 28, "verses": [{"v": 1, "ref": "28:1", "o": "ה֗וֹי עֲטֶ֤רֶת גֵּאוּת֙ שִׁכֹּרֵ֣י אֶפְרַ֔יִם וְ/צִ֥יץ נֹבֵ֖ל צְבִ֣י תִפְאַרְתּ֑/וֹ אֲשֶׁ֛ר עַל רֹ֥אשׁ גֵּֽיא שְׁמָנִ֖ים הֲל֥וּמֵי יָֽיִן", "en": {"kjv": "Woe to the crown of pride, to the drunkards of Ephraim, whose glorious beauty is a fading flower, which are on the head of the fat valleys of them that are overcome with wine!", "web": "Woe to the crown of pride of the drunkards of Ephraim, and to the fading flower of his glorious beauty, which is on the head of the fertile valley of those who are overcome with wine!", "bsb": "Woe to the majestic crown of Ephraim’s drunkards, to the fading flower of his glorious splendor, set on the summit above the fertile valley, the pride of those overcome by wine.", "asv": "Woe to the crown of pride of the drunkards of Ephraim, and to the fading flower of his glorious beauty, which is on the head of the fat valley of them that are overcome with wine!", "ylt": "Woe to the proud crown of the drunkards of Ephraim. And the fading flower of the beauty of his glory, That is on the head of the fat valley of the broken down of wine.", "dra": "Woe to the crown of pride, to the drunkards of Ephraim, and to the fading flower the glory his joy, who were on the head of the fat valley, staggering with wine.", "bbe": "Ho! crown of pride of those who are given up to wine in Ephraim, and the dead flower of his glory which is on the head of those who are overcome by strong drink!", "geneva": "Woe to the crowne of pride, the drunkards of Ephraim: for his glorious beautie shall be a fading flowre, which is vpon the head of the valley of them that be fat, and are ouercome with wine.", "wycliffe": "Wo to the coroun of pride, to the drunkun men of Effraym, and to the flour fallynge doun of the glorie of the ful out ioiyng therof, that weren in the cop of the fatteste valei, and erriden of wyn.", "rotherham": "Alas! for the proud crown of the drunkards of Ephraim, And for his fading wreath of majestic beauty,—Which is on the head of the fertile valley, of them who are overcome with wine.", "darby": "Woe to the crown of pride of the drunkards of Ephraim, and to the fading flower of his glorious adornment, which is on the head of the fat valley of them that are overcome with wine.", "twenty": "", "jps": "Woe to the crown of pride of the drunkards of Ephraim, and to the fading flower of his glorious beauty, which is on the head of the fat valley of them that are smitten down with wine!", "acv": "Woe to the crown of pride of the drunkards of Ephraim, and to the fading flower of his glorious beauty, which is on the head of the fat valley of those who are overcome with wine!", "anderson": "", "haweis": "", "noyes": "Woe to the proud crown of the drunkards of Ephraim, To the fading flower, his glorious beauty, At the head of the rich valley of a people stupefied with wine.", "webster": "Woe to the crown of pride, to the drunkards of Ephraim, whose glorious beauty [is] a fading flower; who [are] on the head of the rich valleys of them that are overcome with wine!", "vulgate": "vae coronae superbiae ebriis Ephraim et flori decidenti gloriae exultationis eius qui erant in vertice vallis pinguissimae errantes a vino;", "brenton": "Woe to the crown of pride, the hirelings of Ephraim, the flower that has fallen from the glory of the top of the fertile mountain, they that are drunken without wine."}}, {"v": 2, "ref": "28:2", "o": "הִנֵּ֨ה חָזָ֤ק וְ/אַמִּץ֙ לַֽ/אדֹנָ֔/י כְּ/זֶ֥רֶם בָּרָ֖ד שַׂ֣עַר קָ֑טֶב כְּ֠/זֶרֶם מַ֣יִם כַּבִּירִ֥ים שֹׁטְפִ֛ים הִנִּ֥יחַ לָ/אָ֖רֶץ בְּ/יָֽד", "en": {"kjv": "Behold, the Lord hath a mighty and strong one, which as a tempest of hail and a destroying storm, as a flood of mighty waters overflowing, shall cast down to the earth with the hand.", "web": "Behold, the Lord has a mighty and strong one. Like a storm of hail, a destroying storm, and like a storm of mighty waters overflowing, he will cast them down to the earth with his hand.", "bsb": "Behold, the Lord has one who is strong and mighty. Like a hailstorm or destructive tempest, like a driving rain or flooding downpour, he will smash that crown to the ground.", "asv": "Behold, the Lord hath a mighty and strong one; as a tempest of hail, a destroying storm, as a tempest of mighty waters overflowing, will he cast down to the earth with the hand.", "ylt": "Lo, a mighty and strong one is to the Lord, As a storm of hail--a destructive shower, As an inundation of mighty waters overflowing, He cast down to the earth with the hand.", "dra": "Behold the Lord is mighty and strong, as a storm of hail: a destroying whirlwind, as the violence of many waters overflowing, and sent forth upon a spacious land.", "bbe": "See, the Lord has a strong and cruel one; like a rain of ice, a storm of destruction, like the overflowing of a strong river, he will violently overcome them.", "geneva": "Beholde, the Lord hath a mightie and strong hoste, like a tempest of haile, and a whirlewinde that ouerthroweth, like a tempest of mightie waters that ouerflowe, which throwe to the ground mightily.", "wycliffe": "Lo! the myyti and strong Lord, as the feersnesse of hail, a whirlwynd brekynge togidere, as the fersnesse of many watris flowynge, and sent out on a large lond.", "rotherham": "Lo! My Lord hath one who is, strong and bold, Like a storm of hail, a destroying tempest, Like a storm of mighty waters overflowing, Hath he thrust it down to the earth with force:", "darby": "Behold, the Lord hath a mighty and strong one, as a storm of hail [and] a destroying tempest; as a storm of mighty waters overflowing, shall he cast down to the earth with might.", "twenty": "", "jps": "Behold, the L-rd hath a mighty and strong one, as a storm of hail, a tempest of destruction, as a storm of mighty waters overflowing, that casteth down to the earth with violence.", "acv": "Behold, the Lord has a mighty and strong one. As a tempest of hail, a destroying storm, as a tempest of mighty waters overflowing, he will cast down to the earth with the hand.", "anderson": "", "haweis": "", "noyes": "Behold a strong, a mighty one from the Lord Like a storm of hail, like a destructive tempest, Like a flood of mighty, overflowing waters, With violence shall dash it to the ground.", "webster": "Behold, the Lord hath a mighty and strong one, [which] as a tempest of hail [and] a destroying storm, as a flood of mighty waters overflowing, shall cast down to the earth with the hand.", "vulgate": "ecce validus et fortis Domini sicut impetus grandinis turbo confringens sicut impetus aquarum multarum inundantium et emissarum super terram spatiosam;", "brenton": "Behold, the anger of the Lord is strong and severe, as descending hail where there is no shelter, violently descending; as a great body of water sweeping away the soil, he shall make rest for the land."}}, {"v": 3, "ref": "28:3", "o": "בְּ/רַגְלַ֖יִם תֵּֽרָמַ֑סְנָה עֲטֶ֥רֶת גֵּא֖וּת שִׁכּוֹרֵ֥י אֶפְרָֽיִם", "en": {"kjv": "The crown of pride, the drunkards of Ephraim, shall be trodden under feet:", "web": "The crown of pride of the drunkards of Ephraim will be trodden under foot.", "bsb": "The majestic crown of Ephraim’s drunkards will be trampled underfoot.", "asv": "The crown of pride of the drunkards of Ephraim shall be trodden under foot:", "ylt": "By feet trodden down is the proud crown of the drunkards of Ephraim,", "dra": "The crown of pride of the drunkards of Ephraim shall be trodden under feet.", "bbe": "The crown of pride of those who are given up to wine in Ephraim will be crushed under foot;", "geneva": "They shall be troden vnder foote, euen the crowne and the pride of the drunkards of Ephraim.", "wycliffe": "The coroun of pride of the drunken men of Effraym schal be defoulid with feet,", "rotherham": "With the feet shall be trodden down, the proud crown of the drunkards of Ephraim,", "darby": "The crown of pride of the drunkards of Ephraim shall be trodden under feet;", "twenty": "", "jps": "The crown of pride of the drunkards of Ephraim shall be trodden under foot;", "acv": "The crown of pride of the drunkards of Ephraim shall be trodden under foot.", "anderson": "", "haweis": "", "noyes": "It shall be trodden under foot, The proud crown of the drunkards of Ephraim.", "webster": "The crown of pride, the drunkards of Ephraim shall be trodden under feet.", "vulgate": "pedibus conculcabitur corona superbiae ebriorum Ephraim;", "brenton": "The crown of pride, the hirelings of Ephraim, shall be beaten down with the hands and with the feet."}}, {"v": 4, "ref": "28:4", "o": "וְֽ/הָ֨יְתָ֜ה צִיצַ֤ת נֹבֵל֙ צְבִ֣י תִפְאַרְתּ֔/וֹ אֲשֶׁ֥ר עַל רֹ֖אשׁ גֵּ֣יא שְׁמָנִ֑ים כְּ/בִכּוּרָהּ֙ בְּ/טֶ֣רֶם קַ֔יִץ אֲשֶׁ֨ר יִרְאֶ֤ה הָֽ/רֹאֶה֙ אוֹתָ֔/הּ בְּ/עוֹדָ֥/הּ בְּ/כַפּ֖/וֹ יִבְלָעֶֽ/נָּה", "en": {"kjv": "And the glorious beauty, which is on the head of the fat valley, shall be a fading flower, and as the hasty fruit before the summer; which when he that looketh upon it seeth, while it is yet in his hand he eateth it up.", "web": "The fading flower of his glorious beauty, which is on the head of the fertile valley, shall be like the first-ripe fig before the summer; which someone picks and eats as soon as he sees it.", "bsb": "The fading flower of his beautiful splendor, set on the summit above the fertile valley, will be like a ripe fig before the summer harvest: Whoever sees it will take it in his hand and swallow it.", "asv": "and the fading flower of his glorious beauty, which is on the head of the fat valley, shall be as the first-ripe fig before the summer; which when he that looketh upon it seeth, while it is yet in his hand he eateth it up.", "ylt": "And the fading flower of the beauty of his glory That is on the head of the fat valley, Hath been as its first-fruit before summer, That its beholder seeth, While it is yet in his hand he swalloweth it.", "dra": "And the fading tower the glory of his joy, who is on the head of the fat valley, shall be as a hasty fruit before the ripeness of autumn: which when he that seeth it shall behold, as soon he taketh it in his hand, he will eat it up.", "bbe": "And the dead flower of his glory, which is on the head of the fertile valley, will be like the first early fruit before the summer; which a man takes and puts in his mouth the minute he sees it.", "geneva": "For his glorious beautie shall be a fading floure, which is vpon the head of the valley of them that be fatte, and as the hastie fruite afore sommer, which when hee that looketh vpon it, seeth it, while it is in his hand, he eateth it.", "wycliffe": "and the flour of glorie of the ful out ioiyng of hym, that is on the cop of valei of fat thingis, schal be fallyng doun, as a tymeli thing bifore the ripenesse of heruest; which whanne a man seynge biholdith, anoon as he takith with hond, he schal deuoure it.", "rotherham": "So shall his fading wreath of majestic beauty, Which is on the head of the fertile valley, become—Like the first-ripe fig before fruit-harvest, Which when he that looketh upon it seeth while it is yet in his hand, he swalloweth it up.", "darby": "and the fading flower of his glorious adornment which is on the head of the fat valley shall be like an early fig before the summer: as soon as he that seeth it perceiveth it, scarcely is it in his hand, he swalloweth it down.", "twenty": "", "jps": "And the fading flower of his glorious beauty, which is on the head of the fat valley, shall be as the first-ripe fig before the summer, which when one looketh upon it, while it is yet in his hand he eateth it up.", "acv": "And the fading flower of his glorious beauty, which is on the head of the fat valley, shall be as the first-ripe fig before the summer, which, when he who looks upon it sees, while it is yet in his hand, he eats it up.", "anderson": "", "haweis": "", "noyes": "And the fading flower, their glorious beauty, At the head of the rich valley, Shall be as the early fig before the time of harvest, Which whoso seeth plucketh immediately, And swalloweth as soon as it is in his hand.", "webster": "And the glorious beauty, which [is] on the head of the rich valley, shall be a fading flower, [and] as the early fruit before the summer; which, [when] he that looketh upon it, seeth while it is yet in his hand he eateth it up.", "vulgate": "et erit flos decidens gloriae exultationis eius qui est super verticem vallis pinguium quasi temporaneum ante maturitatem autumni quod cum aspexerit videns statim ut manu tenuerit devorabit illud;", "brenton": "And the fading flower of the glorious hope on the top of the high mountain shall be as the early fig; he that sees it, before he takes it into his hand, will desire to swallow it down."}}, {"v": 5, "ref": "28:5", "o": "בַּ/יּ֣וֹם הַ/ה֗וּא יִֽהְיֶה֙ יְהוָ֣ה צְבָא֔וֹת לַ/עֲטֶ֣רֶת צְבִ֔י וְ/לִ/צְפִירַ֖ת תִּפְאָרָ֑ה לִ/שְׁאָ֖ר עַמּֽ/וֹ", "en": {"kjv": "In that day shall the Lord of hosts be for a crown of glory, and for a diadem of beauty, unto the residue of his people,", "web": "In that day, Yahweh of Armies will become a crown of glory, and a diadem of beauty, to the residue of his people;", "bsb": "On that day the LORD of Hosts will be a crown of glory, a diadem of splendor to the remnant of His people,", "asv": "In that day will Jehovah of hosts become a crown of glory, and a diadem of beauty, unto the residue of his people;", "ylt": "In that day is Jehovah of Hosts For a crown of beauty, and for a diadem of glory, To the remnant of His people.", "dra": "In that day the Lord of hosts shall be a crown of glory, and a garland of joy to the residue of his people:", "bbe": "In that day will the Lord of armies be a crown of glory, and a fair ornament, to the rest of his people;", "geneva": "In that day shall the Lord of hostes be for a crowne of glory, and for a diademe of beautie vnto the residue of his people:", "wycliffe": "In that dai the Lord of oostis schal be a coroun of glorie, and a garlond of ful out ioiyng, to the residue of his puple;", "rotherham": "In that day, will Yahweh of hosts become A crown of beauty, and A diadem of majesty,—Unto the remnant of his people:", "darby": "In that day will Jehovah of hosts be for a crown of glory, and for a diadem of beauty, unto the remnant of his people;", "twenty": "", "jps": "In that day shall HaShem of hosts be for a crown of glory, and for a diadem of beauty, unto the residue of His people;", "acv": "In that day Jehovah of hosts will become a crown of glory, and a diadem of beauty, to the residue of his people,", "anderson": "", "haweis": "", "noyes": "In that day shall Jehovah of hosts Be a glorious crown, and a beautiful diadem to the residue of his people;", "webster": "In that day will the LORD of hosts be for a crown of glory, and for a diadem of beauty, to the residue of his people,", "vulgate": "in die illa erit Dominus exercituum corona gloriae et sertum exultationis residuo populi sui;", "brenton": "In that day the Lord of hosts shall be the crown of hope, the woven crown of glory, to the remnant of the people."}}, {"v": 6, "ref": "28:6", "o": "וּ/לְ/ר֖וּחַ מִשְׁפָּ֑ט לַ/יּוֹשֵׁב֙ עַל הַ/מִּשְׁפָּ֔ט וְ/לִ֨/גְבוּרָ֔ה מְשִׁיבֵ֥י מִלְחָמָ֖ה שָֽׁעְרָ/ה", "en": {"kjv": "And for a spirit of judgment to him that sitteth in judgment, and for strength to them that turn the battle to the gate.", "web": "and a spirit of justice to him who sits in judgment, and strength to those who turn back the battle at the gate.", "bsb": "a spirit of justice to him who sits in judgment, and a strength to those who repel the onslaught at the gate.", "asv": "and a spirit of justice to him that sitteth in judgment, and strength to them that turn back the battle at the gate.", "ylt": "And for a spirit of judgment To him who is sitting in the judgment, And for might to those turning back the battle to the gate.", "dra": "And a spirit of judgment to him that sitteth in judgment, and strength to them that return out of the battle to the gate.", "bbe": "And a spirit of wisdom to the judge, and strength to those who keep back the attackers at the door of the town.", "geneva": "And for a spirite of iudgement to him that sitteth in iudgement, and for strength vnto them that turne away the battell to the gate.", "wycliffe": "and a spirit of doom to hym that sittith on the trone, and strengthe to hem that turnen ayen fro batel to the yate.", "rotherham": "Even a spirit of justice—to him that presideth over justice, And strength to them who would turn back the battle at the gate.", "darby": "and for a spirit of judgment to him that sitteth in judgment, and for strength to them that turn the battle to the gate.", "twenty": "", "jps": "And for a spirit of judgment to him that sitteth in judgment, and for strength to them that turn back the battle at the gate.", "acv": "and a spirit of justice to him who sits in judgment, and strength to those who turn back the battle at the gate.", "anderson": "", "haweis": "", "noyes": "A spirit of judgment to him that sitteth in judgment, And of strength to them that drive back the enemy to their gates.", "webster": "And for a spirit of judgment to him that sitteth in judgment, and for strength to them that turn the battle to the gate.", "vulgate": "et spiritus iudicii sedenti super iudicium et fortitudo revertentibus de bello ad portam;", "brenton": "They shall be left in the spirit of judgment for judgment, and for the strength of them that hinder slaying."}}, {"v": 7, "ref": "28:7", "o": "וְ/גַם אֵ֨לֶּה֙ בַּ/יַּ֣יִן שָׁג֔וּ וּ/בַ/שֵּׁכָ֖ר תָּע֑וּ כֹּהֵ֣ן וְ/נָבִיא֩ שָׁג֨וּ בַ/שֵּׁכָ֜ר נִבְלְע֣וּ מִן הַ/יַּ֗יִן תָּעוּ֙ מִן הַ/שֵּׁכָ֔ר שָׁגוּ֙ בָּֽ/רֹאֶ֔ה פָּק֖וּ פְּלִילִיָּֽה", "en": {"kjv": "But they also have erred through wine, and through strong drink are out of the way; the priest and the prophet have erred through strong drink, they are swallowed up of wine, they are out of the way through strong drink; they err in vision, they stumble in judgment.", "web": "They also reel with wine, and stagger with strong drink. The priest and the prophet reel with strong drink. They are swallowed up by wine. They stagger with strong drink. They err in vision. They stumble in judgment.", "bsb": "These also stagger from wine and stumble from strong drink: Priests and prophets reel from strong drink and are befuddled by wine. They stumble because of strong drink, muddled in their visions and stumbling in their judgments.", "asv": "And even these reel with wine, and stagger with strong drink; the priest and the prophet reel with strong drink, they are swallowed up of wine, they stagger with strong drink; they err in vision, they stumble in judgment.", "ylt": "And even these through wine have erred, And through strong drink have wandered, Priest and prophet erred through strong drink, They have been swallowed up of the wine, They wandered because of the strong drink, They have erred in seeing, They have stumbled judicially.", "dra": "But these also have been ignorant through wine, and through drunkenness have erred: the priest and the prophet have been ignorant through drunkenness, they are swallowed up with wine, they have gone astray in drunkenness, they have not known him that seeth, they have been ignorant of judgment.", "bbe": "And further, these are uncertain through wine, and have gone out of the right way through strong drink: the priest and the prophet are uncertain through strong drink, they are overcome by wine, they have gone out of the way through strong drink; their vision is false, they go wrong in their decisions.", "geneva": "But they haue erred because of wine, and are out of the way by strong drinke: the priest and the prophet haue erred by strong drinke: they are swallowed vp with wine: they haue gone astraye through strong drinke: they faile in vision: they stumble in iudgement.", "wycliffe": "But also thei knewen not for wyn, and erriden for drunkenesse; the preest and profete knewen not for drunkenesse; thei weren sopun up of wyn, thei erriden in drunkenesse; thei knewen not a profete, thei knewen not doom.", "rotherham": "But as for these, With wine, do they reel, and With strong drink, do they stagger,—Priest and prophet, reel with strong drink They are swallowed up through wine They stagger through strong drink, They reel in prophetic vision, They totter in pronouncing judgment.", "darby": "But these also have erred through wine, and through strong drink are they gone astray. The priest and the prophet have erred through strong drink; they are overpowered by wine, they are gone astray through strong drink; they have erred in vision, they have stumbled [in] judgment.", "twenty": "", "jps": "But these also reel through wine, and stagger through strong drink; the priest and the prophet reel through strong drink, they are confused because of wine, they stagger because of strong drink; they reel in vision, they totter in judgment.", "acv": "And even these reel with wine, and stagger with strong drink. The priest and the prophet reel with strong drink. They are swallowed up of wine. They stagger with strong drink; they err in vision; they stumble in judgment.", "anderson": "", "haweis": "", "noyes": "But even these stagger through wine, And reel through strong drink; The priest and the prophet stagger through strong drink; They are overpowered with wine; They stumble through strong drink; They reel in vision, They stagger in judgment.", "webster": "But they also have erred through wine, and through strong drink are out of the way; the priest and the prophet have erred through strong drink, they are overwhelmed with wine, they are out of the way through strong drink; they err in vision, they stumble [in] judgment.", "vulgate": "verum hii quoque prae vino nescierunt et prae ebrietate erraverunt sacerdos et propheta nescierunt prae ebrietate absorti sunt a vino erraverunt in ebrietate nescierunt videntem ignoraverunt iudicium;", "brenton": "For these have trespassed through wine; they have erred through strong drink: the priest and the prophet are mad through strong drink, they are swallowed up by reason of wine, they have staggered through drunkenness; they have erred: this is their vision."}}, {"v": 8, "ref": "28:8", "o": "כִּ֚י כָּל שֻׁלְחָנ֔וֹת מָלְא֖וּ קִ֣יא צֹאָ֑ה בְּלִ֖י מָקֽוֹם", "en": {"kjv": "For all tables are full of vomit and filthiness, so that there is no place clean.", "web": "For all tables are completely full of filthy vomit and filthiness.", "bsb": "For all their tables are covered with vomit; there is not a place without filth.", "asv": "For all tables are full of vomit and filthiness, so that there is no place clean.", "ylt": "For all tables have been full of vomit, Filth--without place!", "dra": "For all the tables were full of vomit and filth, so that there was no more place.", "bbe": "For all the tables are covered with coughed-up food, so that there is not a clean place.", "geneva": "For all their tables are full of filthy vomiting: no place is cleane.", "wycliffe": "For whi alle bordis weren fillid with spuyng and filthis, so that ther was no more place.", "rotherham": "For, all tables, are full of filthy vomit,—There is no place!", "darby": "For all tables are full of filthy vomit, so that there is no [more] place.", "twenty": "", "jps": "For all tables are full of filthy vomit, and no place is clean.", "acv": "For all tables are full of vomit, filthiness, no place clean.", "anderson": "", "haweis": "", "noyes": "For all their tables are full of filthy vomit, So that there is no place clean.", "webster": "For all tables are full of vomit [and] filthiness, [so that there is] no place [clean].", "vulgate": "omnes enim mensae repletae sunt vomitu sordiumque ita ut non esset ultra locus;", "brenton": "A curse shall devour this counsel, for this is their counsel for the sake of covetousness."}}, {"v": 9, "ref": "28:9", "o": "אֶת מִי֙ יוֹרֶ֣ה דֵעָ֔ה וְ/אֶת מִ֖י יָבִ֣ין שְׁמוּעָ֑ה גְּמוּלֵי֙ מֵֽ/חָלָ֔ב עַתִּיקֵ֖י מִ/שָּׁדָֽיִם", "en": {"kjv": "Whom shall he teach knowledge? and whom shall he make to understand doctrine? them that are weaned from the milk, and drawn from the breasts.", "web": "Whom will he teach knowledge? To whom will he explain the message? Those who are weaned from the milk, and drawn from the breasts?", "bsb": "Whom is He trying to teach? To whom is He explaining His message? To infants just weaned from milk? To babies removed from the breast?", "asv": "Whom will he teach knowledge? and whom will he make to understand the message? them that are weaned from the milk, and drawn from the breasts?", "ylt": "By whom doth He teach knowledge? And by whom doth He cause to understand the report? The weaned from milk, the removed from breasts,", "dra": "Whom shall he teach knowledge? and whom shall he make to understand the hearing? them that are weaned from the milk, that are drawn away from the breasts.", "bbe": "To whom will he give knowledge? and to whom will he make clear the word? Will it be to those who have newly given up milk, and who have only now been taken from the breast?", "geneva": "Whome shall he teache knowledge? and whome shall he make to vnderstand the thinges that hee heareth? them that are weyned from the milke, and drawen from the breastes.", "wycliffe": "Whom schal he teche kunnyng, and whom schal he make to vndurstonde heryng? Men wenyd fro mylk, men drawun awei fro tetis.", "rotherham": "Whom, would he teach knowledge? And, whom, would he cause to understand the message? Them who are weaned from the milk? taken from the breasts?", "darby": "Whom shall he teach knowledge? and whom shall he make to understand the report? Them that are weaned from the milk, withdrawn from the breasts?", "twenty": "", "jps": "Whom shall one teach knowledge? And whom shall one make to understand the message? Them that are weaned from the milk, them that are drawn from the breasts?", "acv": "Whom will he teach knowledge? And whom will he make to understand the message? Those who are weaned from the milk, and drawn from the breasts?", "anderson": "", "haweis": "", "noyes": "\"Whom,\" say they, \"will he teach knowledge, And to whom will he impart instruction? To the weaned from the milk? To those just taken from the breast?", "webster": "Whom shall he teach knowledge? and whom shall he make to understand doctrine? [them that are] weaned from the milk, [and] drawn from the breasts.", "vulgate": "quem docebit scientiam et quem intellegere faciet auditum ablactatos a lacte apulsos ab uberibus;", "brenton": "To whom have we reported evils? and to whom have we reported a message? even to those that are weaned from the milk, who are drawn from the breast."}}, {"v": 10, "ref": "28:10", "o": "כִּ֣י צַ֤ו לָ/צָו֙ צַ֣ו לָ/צָ֔ו קַ֥ו לָ/קָ֖ו קַ֣ו לָ/קָ֑ו זְעֵ֥יר שָׁ֖ם זְעֵ֥יר שָֽׁם", "en": {"kjv": "For precept must be upon precept, precept upon precept; line upon line, line upon line; here a little, and there a little:", "web": "For it is precept on precept, precept on precept; line on line, line on line; here a little, there a little.", "bsb": "For they hear: “Order on order, order on order, line on line, line on line; a little here, a little there.”", "asv": "For it is precept upon precept, precept upon precept; line upon line, line upon line; here a little, there a little.", "ylt": "For rule is on rule, rule on rule, line on line, line on line, A little here, a little there,", "dra": "For command, command again; command, command again; expect, expect again; a little there, a little there.", "bbe": "For it is one rule after another; one line after another; here a little, there a little.", "geneva": "For precept must be vpon precept, precept vpon precept, line vnto line, line vnto line, there a litle, and there a litle.", "wycliffe": "For whi comaunde thou, comaunde thou ayen; comaunde thou, comaunde thou ayen; abide thou, abide thou ayen; abide thou, abide thou ayen; a litil there, a litil there.", "rotherham": "For it is—Precept upon precept, precept upon precept, Line upon line, line upon line,—A little here a little there.", "darby": "For [it is] precept upon precept, precept upon precept; line upon line, line upon line; here a little, there a little. ...", "twenty": "", "jps": "For it is precept by precept, precept by precept, line by line, line by line; here a little, there a little.", "acv": "For it is precept upon precept, precept upon precept, line upon line, line upon line, here a little, there a little.", "anderson": "", "haweis": "", "noyes": "For it is precept upon precept, precept upon precept, Command upon command, command upon command, A little here, and a little there.\"", "webster": "For precept [must be] upon precept, precept upon precept; line upon line, line upon line; here a little, [and] there a little:", "vulgate": "quia manda remanda manda remanda expecta reexpecta expecta reexpecta modicum ibi modicum ibi;", "brenton": "Expect thou affliction on affliction, hope upon hope: yet a little, and yet a little,"}}, {"v": 11, "ref": "28:11", "o": "כִּ֚י בְּ/לַעֲגֵ֣י שָׂפָ֔ה וּ/בְ/לָשׁ֖וֹן אַחֶ֑רֶת יְדַבֵּ֖ר אֶל הָ/עָ֥ם הַ/זֶּֽה", "en": {"kjv": "For with stammering lips and another tongue will he speak to this people.", "web": "But he will speak to this nation with stammering lips and in another language;", "bsb": "Indeed, with mocking lips and foreign tongues, He will speak to this people", "asv": "Nay, but bymen of strange lips and with another tongue will he speak to this people;", "ylt": "For by scorned lip, and by another tongue, Doth He speak unto this people.", "dra": "For with the speech of lips, and with another tongue he will speak to this people.", "bbe": "No, but with broken talk, and with a strange tongue, he will give his word to this people:", "geneva": "For with a stammering tongue and with a strange language shall he speake vnto this people.", "wycliffe": "For whi in speche of lippe, and in other langage he schal speke to this puple,", "rotherham": "For, with a jabbering lip, and with an alien tongue, must he speak unto this people!", "darby": "For with stammering lips and a strange tongue will he speak to this people;", "twenty": "", "jps": "For with stammering lips and with a strange tongue shall it be spoken to this people;", "acv": "No, but by men of strange lips and with another tongue he will speak to this people,", "anderson": "", "haweis": "", "noyes": "Yea, with stammering lips and a strange tongue He shall indeed speak to this people;", "webster": "For with stammering lips and another tongue will he speak to this people.", "vulgate": "in loquella enim labii et lingua altera loquetur ad populum istum;", "brenton": "by reason of the contemptuous words of the lips, by means of another language: for they shall speak to this people, saying to them,"}}, {"v": 12, "ref": "28:12", "o": "אֲשֶׁ֣ר אָמַ֣ר אֲלֵי/הֶ֗ם זֹ֤את הַ/מְּנוּחָה֙ הָנִ֣יחוּ לֶֽ/עָיֵ֔ף וְ/זֹ֖את הַ/מַּרְגֵּעָ֑ה וְ/לֹ֥א אָב֖וּא שְׁמֽוֹעַ", "en": {"kjv": "To whom he said, This is the rest wherewith ye may cause the weary to rest; and this is the refreshing: yet they would not hear.", "web": "to whom he said, “This is the resting place. Give rest to weary”; and “This is the refreshing”; yet they would not hear.", "bsb": "to whom He has said: “This is the place of rest, let the weary rest; this is the place of repose.” But they would not listen.", "asv": "to whom he said, This is the rest, give ye rest to him that is weary; and this is the refreshing: yet they would not hear.", "ylt": "Unto whom He hath said, `This is the rest, give ye rest to the weary, And this--the refreshing:' And they have not been willing to hear,", "dra": "To whom he said: This is my rest, refresh the weary, and this is my refreshing: and they would not hear.", "bbe": "To whom he said, This is the rest, give rest to him who is tired; and by this you may get new strength; but they would not give ear.", "geneva": "Vnto whome hee saide, This is the rest: giue rest to him that is weary: and this is the refreshing, but they would not heare.", "wycliffe": "to which he seide, This is my reste; refreische ye a weri man, and this is my refreischyng; and thei nolden here.", "rotherham": "To whom he said—This, is the rest—give ye rest to the weary, and This, is the quietness,—But they were unwilling to hear.", "darby": "to whom he said, This is the rest: cause the weary to rest; and this is the refreshing. But they would not hear.", "twenty": "", "jps": "To whom it was said: 'This is the rest, give ye rest to the weary; and this is the refreshing'; yet they would not hear.", "acv": "to whom he said, This is the rest. Give ye rest to him who is weary. And this is the refreshing. Yet they would not hear.", "anderson": "", "haweis": "", "noyes": "He that said to them, \"This is the way of rest, give rest to the weary; This is the way of safety\"; But they would not hear.", "webster": "To whom he said, This [is] the rest [with which] ye may cause the weary to rest; and this [is] the refreshing: yet they would not hear.", "vulgate": "cui dixit haec requies reficite lassum et hoc est meum refrigerium et noluerunt audire;", "brenton": "This is the rest to him that is hungry, and this is the calamity: but they would not hear."}}, {"v": 13, "ref": "28:13", "o": "וְ/הָיָ֨ה לָ/הֶ֜ם דְּבַר יְהוָ֗ה צַ֣ו לָ/צָ֞ו צַ֤ו לָ/צָו֙ קַ֤ו לָ/קָו֙ קַ֣ו לָ/קָ֔ו זְעֵ֥יר שָׁ֖ם זְעֵ֣יר שָׁ֑ם לְמַ֨עַן יֵלְכ֜וּ וְ/כָשְׁל֤וּ אָחוֹר֙ וְ/נִשְׁבָּ֔רוּ וְ/נוֹקְשׁ֖וּ וְ/נִלְכָּֽדוּ", "en": {"kjv": "But the word of the Lord was unto them precept upon precept, precept upon precept; line upon line, line upon line; here a little, and there a little; that they might go, and fall backward, and be broken, and snared, and taken.", "web": "Therefore Yahweh’s word will be to them precept on precept, precept on precept; line on line, line on line; here a little, there a little; that they may go, fall backward, be broken, be snared, and be taken.", "bsb": "Then the word of the LORD to them will become: “Order on order, order on order, line on line, line on line; a little here, a little there,” so that they will go stumbling backward and will be injured, ensnared, and captured.", "asv": "Therefore shall the word of Jehovah be unto them precept upon precept, precept upon precept; line upon line, line upon line; here a little, there a little; that they may go, and fall backward, and be broken, and snared, and taken.", "ylt": "And to whom a word of Jehovah hath been, Rule on rule, rule on rule, line on line, line on line, A little here, a little there, So that they go and have stumbled backward, And been broken, and snared, and captured.", "dra": "And the word of the Lord shall be to them: Command, command again; command, command again; expect, expect again; a little there, a little there: that they may go, and fall backward, and be broken, and snared, and taken.", "bbe": "For this cause the word of the Lord will be to them rule after rule, line after line, here a little, there a little; so that they may go on their way, and falling back may be broken, and taken in the net.", "geneva": "Therefore shall the worde of the Lord be vnto them precept vpon precept, precept vpon precept, line vnto line, line vnto line, there a litle and there a litle, that they may goe, and fall backward, and be broken, and be snared, and be taken.", "wycliffe": "And the word of the Lord schal be to hem, Sende thou, sende thou ayen; send thou, sende thou ayen; abide thou, abide thou ayen; abide thou, abide thou ayen; a litil there, a litil there; that thei go, and falle backward, and be al to-brokun, and be snarid, and be takun.", "rotherham": "So the word of Yahweh must be to them—Precept upon precept, precept upon precept, Line upon line, line upon line, A little here, a little there,—That they may go and fall backward and be torn and snared and captured.", "darby": "And the word of Jehovah was unto them precept upon precept, precept upon precept, line upon line, line upon line, here a little, there a little: that they might go, and fall backward, and be broken, and snared, and taken.", "twenty": "", "jps": "And so the word of HaShem is unto them precept by precept, precept by precept, line by line, line by line; here a little, there a little; that they may go, and fall backward, and be broken, and snared, and taken.", "acv": "Therefore the word of Jehovah shall be to them precept upon precept, precept upon precept, line upon line, line upon line, here a little, there a little, that they may go, and fall backward, and be broken, and snared, and taken.", "anderson": "", "haweis": "", "noyes": "Then shall the word of Jehovah be indeed to them \"Precept upon precept, precept upon precept, Command upon command, command upon command, A little here, and a little there,\" So that they shall go on, and fall backwards, and be broken, And be snared and caught.", "webster": "But the word of the LORD was to them, precept upon precept, precept upon precept; line upon line, line upon line; here a little, [and] there a little; that they might go, and fall backward, and be broken, and snared, and taken.", "vulgate": "et erit eis verbum Domini manda remanda manda remanda expecta reexpecta expecta reexpecta modicum ibi modicum ibi ut vadant et cadant retrorsum et conterantur et inlaqueentur et capiantur;", "brenton": "Therefore the oracle of God shall be to them affliction on affliction, hope on hope, yet a little, and yet a little, that they may go and fall backward; and they shall be crushed and shall be in danger, and shall be taken."}}, {"v": 14, "ref": "28:14", "o": "לָ/כֵ֛ן שִׁמְע֥וּ דְבַר יְהוָ֖ה אַנְשֵׁ֣י לָצ֑וֹן מֹֽשְׁלֵי֙ הָ/עָ֣ם הַ/זֶּ֔ה אֲשֶׁ֖ר בִּ/ירוּשָׁלִָֽם", "en": {"kjv": "Wherefore hear the word of the Lord, ye scornful men, that rule this people which is in Jerusalem.", "web": "Therefore hear Yahweh’s word, you scoffers, that rule this people in Jerusalem:", "bsb": "Therefore hear the word of the LORD, O scoffers who rule this people in Jerusalem.", "asv": "Wherefore hear the word of Jehovah, ye scoffers, that rule this people that is in Jerusalem:", "ylt": "Therefore, hear a word of Jehovah, ye men of scorning, Ruling this people that is in Jerusalem.", "dra": "Wherefore hear the word of the Lord, ye scornful men, who rule over my people that is in Jerusalem.", "bbe": "Give ear then to the word of the Lord, you men of pride, the rulers of this people in Jerusalem:", "geneva": "Wherefore, heare the worde of the Lord, ye scornefull men that rule this people, which is at Ierusalem.", "wycliffe": "For this thing, ye men scorneris, that ben lordis ouer my puple which is in Jerusalem, here the word of the Lord.", "rotherham": "Wherefore, hear ye the word of Yahweh, Ye men who scoff,—Ye rulers of this people that is in Jerusalem.", "darby": "Therefore hear the word of Jehovah, ye scornful men, that rule this people which is in Jerusalem.", "twenty": "", "jps": "Wherefore hear the word of HaShem, ye scoffers, the ballad-mongers of this people which is in Jerusalem:", "acv": "Therefore hear the word of Jehovah, ye scoffers, who rule this people that is in Jerusalem.", "anderson": "", "haweis": "", "noyes": "Wherefore hear ye the word of Jehovah, Ye scoffers, who rule this people in Jerusalem!", "webster": "Wherefore hear the word of the LORD, ye scornful men, that rule this people which [is] in Jerusalem.", "vulgate": "propter hoc audite verbum Domini viri inlusores qui dominamini super populum meum qui est in Hierusalem;", "brenton": "Therefore hear ye the word of the Lord, ye afflicted men, and ye princes of this people that is in Jerusalem."}}, {"v": 15, "ref": "28:15", "o": "כִּ֣י אֲמַרְתֶּ֗ם כָּרַ֤תְנֽוּ בְרִית֙ אֶת מָ֔וֶת וְ/עִם שְׁא֖וֹל עָשִׂ֣ינוּ חֹזֶ֑ה שיט שׁ֣וֹט שׁוֹטֵ֤ף כִּֽי עבר יַֽעֲבֹר֙ לֹ֣א יְבוֹאֵ֔/נוּ כִּ֣י שַׂ֧מְנוּ כָזָ֛ב מַחְסֵ֖/נוּ וּ/בַ/שֶּׁ֥קֶר נִסְתָּֽרְנוּ", "en": {"kjv": "Because ye have said, We have made a covenant with death, and with hell are we at agreement; when the overflowing scourge shall pass through, it shall not come unto us: for we have made lies our refuge, and under falsehood have we hid ourselves:", "web": "“Because you have said, ‘We have made a covenant with death, and with Sheol are we in agreement. When the overflowing scourge passes through, it won’t come to us; for we have made lies our refuge, and we have hidden ourselves under falsehood.’”", "bsb": "For you said, “We have made a covenant with death; we have fashioned an agreement with Sheol. When the overwhelming scourge passes through it will not touch us, because we have made lies our refuge and falsehood our hiding place.”", "asv": "Because ye have said, We have made a covenant with death, and with Sheol are we at agreement; when the overflowing scourge shall pass through, it shall not come unto us; for we have made lies our refuge, and under falsehood have we hid ourselves:", "ylt": "Because ye have said: `We have made a covenant with death, And with Sheol we have made a provision, An overflowing scourge, when it passeth over, Doth not meet us, Though we have made a lie our refuge, And in falsehood have been hidden.'", "dra": "For you have said: We have entered into a league with death, and we have made a covenant with hell. When the overflowing scourge shall pass through, it shall not come upon us: for we have placed our hope in lies, and by falsehood we are protected.", "bbe": "Because you have said, We have made death our friend, and with the underworld we have made an agreement; when the overflowing waters come through they will not come near us; for we are looking to false words for help, taking cover in what is untrue:", "geneva": "Because ye haue said, We haue made a couenant with death, and with hell are we at agreement: though a scourge runne ouer, and passe through, it shall not come at vs: for we haue made falshood our refuge, and vnder vanitie are we hid,", "wycliffe": "For ye seiden, We han smyte a boond of pees with deth, and we han maad couenaunt with helle; a scourge flowynge whanne it schal passe, schal not come on vs, for we han set a leesyng oure hope, and we ben kyuered with a leesyng.", "rotherham": "Because ye have said—We have solemnised a covenant with death, And with hades, have we effected a vision,—The overflowing scourge when it sweepeth by, shall not reach unto us, For we have made lying our refuge. And in falsehood, have we hid ourselves,", "darby": "For ye have said, We have made a covenant with death, and with Sheol have we made an agreement; when the overflowing scourge shall pass through, it shall not come unto us; for we have made lies our refuge, and under falsehood have we hid ourselves.", "twenty": "", "jps": "Because ye have said: 'We have made a covenant with death, and with the nether-world are we at agreement; when the scouring scourge shall pass through, it shall not come unto us; for we have made lies our refuge, and in falsehood have we hid ourselves';", "acv": "Because ye have said, We have made a covenant with death, and we are at agreement with Sheol. When the overflowing scourge shall pass through it shall not come to us, for we have made lies our refuge, and we have hid ourselves under falsehood.", "anderson": "", "haweis": "", "noyes": "Since ye say, \"We have entered into a covenant with death, And with the under-world have we made an agreement, The overflowing scourge, when it passeth through, shall not reach us; For we have made falsehood our refuge, And in deceit we have hidden ourselves.\"", "webster": "Because ye have said, We have made a covenant with death, and with hell are we in agreement; when the overflowing scourge shall pass through, it shall not reach us: for we have made lies our refuge, and under falsehood have we hid ourselves:", "vulgate": "dixistis enim percussimus foedus cum morte et cum inferno fecimus pactum flagellum inundans cum transierit non veniet super nos quia posuimus mendacium spem nostram et mendacio protecti sumus;", "brenton": "Because ye have said, We have made a covenant with Hades, and agreements with death; if the rushing storm should pass, it shall not come upon us: we have made falsehood our hope, and by falsehood shall we be protected:"}}, {"v": 16, "ref": "28:16", "o": "לָ/כֵ֗ן כֹּ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה הִנְ/נִ֛י יִסַּ֥ד בְּ/צִיּ֖וֹן אָ֑בֶן אֶ֣בֶן בֹּ֜חַן פִּנַּ֤ת יִקְרַת֙ מוּסָ֣ד מוּסָּ֔ד הַֽ/מַּאֲמִ֖ין לֹ֥א יָחִֽישׁ", "en": {"kjv": "Therefore thus saith the Lord God, Behold, I lay in Zion for a foundation a stone, a tried stone, a precious corner stone, a sure foundation: he that believeth shall not make haste.", "web": "Therefore thus says the Lord Yahweh, “Behold, I lay in Zion for a foundation a stone, a tried stone, a precious cornerstone of a sure foundation. He who believes shall not act hastily.", "bsb": "So this is what the Lord GOD says: “See, I lay a stone in Zion, a tested stone, a precious cornerstone, a sure foundation; the one who believes will never be shaken.", "asv": "therefore thus saith the Lord Jehovah, Behold, I lay in Zion for a foundation a stone, a tried stone, a precious corner-stone of sure foundation: he that believeth shall not be in haste.", "ylt": "Therefore, thus said the Lord Jehovah: `Lo, I am laying a foundation in Zion, A stone--a tried stone, a corner stone precious, a settled foundation, He who is believing doth not make haste.", "dra": "Therefore thus saith the Lord God: Behold I will lay a stone in the foundations of Sion, a tried stone, a corner stone, a precious stone, founded in the foundation. He that believeth, let him not hasten.", "bbe": "For this cause says the Lord God, See, I am placing in Zion as a base, a stone, a tested stone, an angle-stone which is certain and of great value: and he who has faith will not give way.", "geneva": "Therefore thus saith the Lord God, Behold, I will laye in Zion a stone, a tried stone, a precious corner stone, a sure foundation. Hee that beleeueth, shall not make haste.", "wycliffe": "Therfor the Lord God seith these thingis, Lo! Y schal sende in the foundementis of Sion a corner stoon preciouse, preuyd, foundid in the foundement; he that bileueth, schal not haaste.", "rotherham": "Therefore, Thus, saith My Lord, Yahweh, Behold me! founding in Zion a stone, A stone of testing, The costly corner of a well-laid foundation, he that trusteth, shall not make haste!", "darby": "Therefore thus saith the Lord Jehovah: Behold, I lay for foundation in Zion a stone, a tried stone, a precious corner-stone, a sure foundation: he that trusteth shall not make haste.", "twenty": "", "jps": "Therefore thus saith the L-rd GOD: Behold, I lay in Zion for a foundation a stone, a tried stone, a costly corner-stone of sure foundation; he that believeth shall not make haste.", "acv": "Therefore thus says the lord Jehovah, Behold, I lay in Zion for a foundation, a stone, a tried stone, a precious corner-stone, a sure foundation. He who believes in him shall, no, not be shamed.", "anderson": "", "haweis": "", "noyes": "Therefore thus saith the Lord Jehovah: Behold, I have laid in Zion as a foundation a stone, A tried stone, a precious corner-stone, a sure foundation; He that trusteth shall not flee away.", "webster": "Therefore thus saith the Lord GOD, Behold, I lay in Zion for a foundation a stone, a tried stone, a precious corner [stone], a sure foundation: he that believeth shall not make haste.", "vulgate": "idcirco haec dicit Dominus Deus ecce ego mittam in fundamentis Sion lapidem lapidem probatum angularem pretiosum in fundamento fundatum qui crediderit non festinet;", "brenton": "Therefore thus saith the Lord, even the Lord, Behold, I lay for the foundations of Sion a costly stone, a choice, a corner-stone, a precious stone, for its foundations; and he that believes on him shall by no means be ashamed."}}, {"v": 17, "ref": "28:17", "o": "וְ/שַׂמְתִּ֤י מִשְׁפָּט֙ לְ/קָ֔ו וּ/צְדָקָ֖ה לְ/מִשְׁקָ֑לֶת וְ/יָעָ֤ה בָרָד֙ מַחְסֵ֣ה כָזָ֔ב וְ/סֵ֥תֶר מַ֖יִם יִשְׁטֹֽפוּ", "en": {"kjv": "Judgment also will I lay to the line, and righteousness to the plummet: and the hail shall sweep away the refuge of lies, and the waters shall overflow the hiding place.", "web": "I will make justice the measuring line, and righteousness the plumb line. The hail will sweep away the refuge of lies, and the waters will overflow the hiding place.", "bsb": "I will make justice the measuring line and righteousness the level. Hail will sweep away your refuge of lies, and water will flood your hiding place.", "asv": "And I will make justice the line, and righteousness the plummet; and the hail shall sweep away the refuge of lies, and the waters shall overflow the hiding-place.", "ylt": "And I have put judgment for a line, And righteousness for a plummet, And sweep away doth hail the refuge of lies, And the secret hiding-place do waters overflow.", "dra": "And I will set judgment in weight, and justice in measure: and hail shall overturn the hope of falsehood: and waters shall overflow its protection.", "bbe": "And I will make right decision the measuring-line, and righteousness the weight: and the ice-storm will take away the safe place of false words, and the secret place will be covered by the flowing waters.", "geneva": "Iudgement also will I laye to the rule, and righteousnesse to the balance, and the haile shall sweepe away the vaine confidence, and the waters shall ouerflowe the secret place.", "wycliffe": "And Y schal sette doom in weiyte, and riytfulnesse in mesure; and hail schal distrie the hope of leesyng, and watris schulen flowe on proteccioun. And youre boond of pees with deth schal be don awei,", "rotherham": "But I will make—Justice the line, and Righteousness the plummet,—And the hail shall, sweep away, your refuge of lying, And your hiding-place, the waters shall overflow;", "darby": "And I will appoint judgment for a line, and righteousness for a plummet; and the hail shall sweep away the refuge of lies, and the waters shall overflow the hiding-place.", "twenty": "", "jps": "And I will make justice the line, and righteousness the plummet; and the hail shall sweep away the refuge of lies, and the waters shall overflow the hiding-place.", "acv": "And I will make justice the line, and righteousness the plummet. And the hail shall sweep away the refuge of lies, and the waters shall overflow the hiding-place.", "anderson": "", "haweis": "", "noyes": "I will make justice a line, And righteousness a plummet, And the hail shall sweep away the refuge of falsehood, And the waters shall overwhelm its hiding-place;", "webster": "Judgment also will I lay to the line, and righteousness to the plummet: and the hail shall sweep away the refuge of lies, and the waters shall overflow the hiding-place.", "vulgate": "et ponam iudicium in pondere et iustitiam in mensura et subvertet grando spem mendacii et protectionem aquae inundabunt;", "brenton": "And I will cause judgment to be for hope, and my compassion shall be for just measures, and ye that trust vainly in falsehood shall fall: for the storm shall by no means pass by you,"}}, {"v": 18, "ref": "28:18", "o": "וְ/כֻפַּ֤ר בְּרִֽיתְ/כֶם֙ אֶת מָ֔וֶת וְ/חָזוּתְ/כֶ֥ם אֶת שְׁא֖וֹל לֹ֣א תָק֑וּם שׁ֤וֹט שׁוֹטֵף֙ כִּ֣י יַֽעֲבֹ֔ר וִ/הְיִ֥יתֶם ל֖/וֹ לְ/מִרְמָֽס", "en": {"kjv": "And your covenant with death shall be disannulled, and your agreement with hell shall not stand; when the overflowing scourge shall pass through, then ye shall be trodden down by it.", "web": "Your covenant with death shall be annulled, and your agreement with Sheol shall not stand. When the overflowing scourge passes through, then you will be trampled down by it.", "bsb": "Your covenant with death will be dissolved, and your agreement with Sheol will not stand. When the overwhelming scourge passes through, you will be trampled by it.", "asv": "And your covenant with death shall be annulled, and your agreement with Sheol shall not stand; when the overflowing scourge shall pass through, then ye shall be trodden down by it.", "ylt": "And disannulled hath been your covenant with death, And your provision with Sheol doth not stand, An overflowing scourge, when it passeth over, Then ye have been to it for a treading-place.", "dra": "And your league with death shall be abolished, and your covenant with hell shall not stand: when the overflowing scourge shall pass, you shall be trodden down by it.", "bbe": "And the help you were looking for from death will come to nothing, and your agreement with the underworld will be broken; when the overflowing waters come through, then you will be overcome by them.", "geneva": "And your couenant with death shalbe disanulled, and your agreement with hell shall not stand: when a scourge shall runne ouer and passe through, then shall ye be trode downe by it.", "wycliffe": "and youre couenaunt with helle schal not stonde; whanne the scourge flowynge schal passe, ye schulen be to it in to defoulyng.", "rotherham": "So shall be wiped out your covenant with death, And your vision with hades, not stand,—When the overflowing scourge, sweepeth past, then shall ye be thereby beaten down:", "darby": "And your covenant with death shall be annulled, and your agreement with Sheol shall not stand; when the overflowing scourge shall pass through, ye shall be trodden down by it.", "twenty": "", "jps": "And your covenant with death shall be disannulled and your agreement with the nether-world shall not stand; when the scouring scourge shall pass through, then ye shall be trodden down by it,", "acv": "And your covenant with death shall be annulled, and your agreement with Sheol shall not stand. When the overflowing scourge shall pass through, then ye shall be trodden down by it.", "anderson": "", "haweis": "", "noyes": "And your covenant with death shall be broken, And your agreement with the under-world shall not stand; When the overflowing scourge shall pass through, By it shall ye be beaten down.", "webster": "And your covenant with death shall be disannulled, and your agreement with hell shall not stand; when the overflowing scourge shall pass through, then ye shall be trodden down by it.", "vulgate": "et delebitur foedus vestrum cum morte et pactum vestrum cum inferno non stabit flagellum inundans cum transierit eritis ei in conculcationem;", "brenton": "except it also take away your covenant of death, and your trust in Hades shall by no means stand: if the rushing storm should come upon you, ye shall be beaten down by it."}}, {"v": 19, "ref": "28:19", "o": "מִ/דֵּ֤י עָבְר/וֹ֙ יִקַּ֣ח אֶתְ/כֶ֔ם כִּֽי בַ/בֹּ֧קֶר בַּ/בֹּ֛קֶר יַעֲבֹ֖ר בַּ/יּ֣וֹם וּ/בַ/לָּ֑יְלָה וְ/הָיָ֥ה רַק זְוָעָ֖ה הָבִ֥ין שְׁמוּעָֽה", "en": {"kjv": "From the time that it goeth forth it shall take you: for morning by morning shall it pass over, by day and by night: and it shall be a vexation only to understand the report.", "web": "As often as it passes through, it will seize you; for morning by morning it will pass through, by day and by night; and it will be nothing but terror to understand the message.”", "bsb": "As often as it passes through, it will carry you away; it will sweep through morning after morning, by day and by night.” The understanding of this message will bring sheer terror.", "asv": "As often as it passeth through, it shall take you; for morning by morning shall it pass through, by day and by night: and it shall be nought but terror to understand the message.", "ylt": "From the fulness of its passing over it taketh you, For morning by morning it passeth over, By day and by night, And it hath been only a trembling to consider the report.", "dra": "Whensoever it shall pass through, it shall take you away: because in the morning early it shall pass through, in the day and in the night, and vexation alone shall make you understand what you hear.", "bbe": "Whenever they come through they will overtake you; for they will come through morning after morning, by day and by night: and the news will be nothing but fear.", "geneva": "When it passeth ouer, it shall take you away: for it shall passe through euery morning in the day, and in the night, and there shalbe onely feare to make you to vnderstand the hearing.", "wycliffe": "Whanne euer it schal passe, it schal take awei yow; for whi erli in the grey morewtid it schal passe, in dai and niyt; and oonli trauel aloone schal yyue vndurstondyng to heryng.", "rotherham": "As often as it sweepeth past, it shall take you away, For morning by morning, shall it pass along. By day and by night,—And it shall be nothing less than a terror to make out the message;", "darby": "As it passeth through it shall take you; for morning by morning shall it pass through, by day and by night; and it shall be terror only to understand the report.", "twenty": "", "jps": "As often as it passeth through, it shall take you; for morning by morning shall it pass through, by day and by night; and it shall be sheer terror to understand the message.", "acv": "As often as it passes though, it shall take you. For morning by morning it shall pass through, by day and by night. And it shall be nothing but terror to understand the report.", "anderson": "", "haweis": "", "noyes": "As often as it passeth through, it shall bear you away; For every morning shall it pass through, By day and by night; Even to hear the rumor of it shall be terrible.", "webster": "From the time that it goeth forth it shall take you: for morning by morning shall it pass over, by day and by night: and it shall be a vexation only [to] understand the report.", "vulgate": "quandocumque pertransierit tollet vos quoniam mane diluculo pertransibit in die et in nocte et tantummodo sola vexatio intellectum dabit auditui;", "brenton": "Whenever it shall pass by, it shall take you; morning by morning it shall pass by in the day, and in the night there shall be an evil hope. Learn to hear,"}}, {"v": 20, "ref": "28:20", "o": "כִּֽי קָצַ֥ר הַ/מַּצָּ֖ע מֵֽ/הִשְׂתָּרֵ֑עַ וְ/הַ/מַּסֵּכָ֥ה צָ֖רָה כְּ/הִתְכַּנֵּֽס", "en": {"kjv": "For the bed is shorter than that a man can stretch himself on it: and the covering narrower than that he can wrap himself in it.", "web": "For the bed is too short to stretch out on, and the blanket is too narrow to wrap oneself in.", "bsb": "Indeed, the bed is too short to stretch out on, and the blanket too small to wrap around you.", "asv": "For the bed is shorter than that a man can stretch himself on it; and the covering narrower than that he can wrap himself in it.", "ylt": "For shorter hath been the bed Than to stretch one's self out in, And the covering hath been narrower Than to wrap one's self up in.", "dra": "For the bed is straitened, so that one must fall out, and a short covering cannot cover both.", "bbe": "For the bed is not long enough for a man to be stretched out on: and the cover is not wide enough for him to be covered with.", "geneva": "For the bed is streight that it can not suffice, and the couering narowe that one can not wrappe himselfe.", "wycliffe": "Forsothe the bed is streit, so that the tother falle doun; and a schort mentil schal not hile euer either.", "rotherham": "For too short is the couch to stretch oneself out,—And, the coverlet, too narrow, when one draweth up his feet.", "darby": "For the bed is too short to stretch oneself on, and the covering too narrow when he would wrap himself in it.", "twenty": "", "jps": "For the bed is too short for a man to stretch himself; and the covering too narrow when he gathereth himself up.", "acv": "For the bed is shorter than what a man can stretch himself on it, and the covering narrower than what he can wrap himself in it.", "anderson": "", "haweis": "", "noyes": "Yea, the bed is too short for one to stretch himself on it, And the covering too narrow for one to wrap himself in it.", "webster": "For the bed is shorter than that [a man] can stretch himself [on it]: and the covering narrower than that he can wrap himself [in it].", "vulgate": "coangustatum est enim stratum ita ut alter decidat et pallium breve utrumque operire non potest;", "brenton": "ye that are distressed; we cannot fight, but we are ourselves too weak for you to be gathered."}}, {"v": 21, "ref": "28:21", "o": "כִּ֤י כְ/הַר פְּרָצִים֙ יָק֣וּם יְהוָ֔ה כְּ/עֵ֖מֶק בְּ/גִבְע֣וֹן יִרְגָּ֑ז לַ/עֲשׂ֤וֹת מַעֲשֵׂ֨/הוּ֙ זָ֣ר מַעֲשֵׂ֔/הוּ וְ/לַֽ/עֲבֹד֙ עֲבֹ֣דָת֔/וֹ נָכְרִיָּ֖ה עֲבֹדָתֽ/וֹ", "en": {"kjv": "For the Lord shall rise up as in mount Perazim, he shall be wroth as in the valley of Gibeon, that he may do his work, his strange work; and bring to pass his act, his strange act.", "web": "For Yahweh will rise up as on Mount Perazim. He will be angry as in the valley of Gibeon; that he may do his work, his unusual work, and bring to pass his act, his extraordinary act.", "bsb": "For the LORD will rise up as at Mount Perazim. He will rouse Himself as in the Valley of Gibeon, to do His work, His strange work, and to perform His task, His disturbing task.", "asv": "For Jehovah will rise up as in mount Perazim, he will be wroth as in the valley of Gibeon; that he may do his work, his strange work, and bring to pass his act, his strange act.", "ylt": "For as at mount Perazim rise doth Jehovah, As at the valley in Gibeon He is troubled, To do His work--strange is His work, And to do His deed--strange is His deed.'", "dra": "For the Lord shall stand up as in the mountain of divisions: he shall be angry as in the valley which is in Gabaon: that he may do his work, his strange work: that he may perform his work, his work is strange to him.", "bbe": "For the Lord will come up as on Mount Perazim, he will be moved to wrath as in the valley of Gibeon; so that he may do his work--strange is his work; and give effect to his act--unnatural is his act.", "geneva": "For the Lord shall stand as in mount Perazim: hee shall be wroth as in the valley of Gibeon, that he may do his worke, his strage worke, and bring to passe his acte, his strange acte.", "wycliffe": "For as in the hil of departyngis the Lord schal stonde, as in the valei, which is in Gabaon, he schal be wroth, that he do his werk; his werk alien, that he worche his werk; his werk is straunge fro hym.", "rotherham": "For as in Mount Perazim, will Yahweh, arise, As in the vale of Gibeon, will he be stirred,—To do his work—foreign is his work, And to perform his task—strange is his task.", "darby": "For Jehovah will rise up as on mount Perazim, he will be moved with anger as in the valley of Gibeon; that he may do his work, his strange work, and perform his act, his unwonted act.", "twenty": "", "jps": "For HaShem will rise up as in mount Perazim, He will be wroth as in the valley of Gibeon; that He may do His work, strange is His work, and bring to pass His act, strange is His act.", "acv": "For Jehovah will rise up as in mount Perazim. He will be angry as in the valley of Gibeon, that he may do his work, his strange work, and bring to pass his act, his strange act.", "anderson": "", "haweis": "", "noyes": "For Jehovah will rise up, as in mount Perazim; He will be moved with anger, as in the valley of Gibeon, To perform his act, his strange act, And to execute his work, his strange work.", "webster": "For the LORD will rise as [on] mount Perazim, he will be wroth as [in] the valley of Gibeon, that he may do his work, his strange work; and bring to pass his act, his strange act.", "vulgate": "sicut enim in monte Divisionum stabit Dominus sicut in valle quae est in Gabao irascetur ut faciat opus suum alienum opus eius ut operetur opus suum peregrinum est opus ab eo;", "brenton": "The Lord shall rise up as a mountain of ungodly men, and shall be in the valley of Gabaon; he shall perform his works with wrath, even a work of bitterness, and his wrath shall deal strangely, and his destruction shall be strange."}}, {"v": 22, "ref": "28:22", "o": "וְ/עַתָּה֙ אַל תִּתְלוֹצָ֔צוּ פֶּֽן יֶחְזְק֖וּ מֽוֹסְרֵי/כֶ֑ם כִּֽי כָלָ֨ה וְ/נֶחֱרָצָ֜ה שָׁמַ֗עְתִּי מֵ/אֵ֨ת אֲדֹנָ֧/י יְהוִ֛ה צְבָא֖וֹת עַל כָּל הָ/אָֽרֶץ", "en": {"kjv": "Now therefore be ye not mockers, lest your bands be made strong: for I have heard from the Lord God of hosts a consumption, even determined upon the whole earth.", "web": "Now therefore don’t be scoffers, lest your bonds be made strong; for I have heard a decree of destruction from the Lord, Yahweh of Armies, on the whole earth.", "bsb": "So now, do not mock, or your shackles will become heavier. Indeed, I have heard from the Lord GOD of Hosts a decree of destruction against the whole land.", "asv": "Now therefore be ye not scoffers, lest your bonds be made strong; for a decree of destruction have I heard from the Lord, Jehovah of hosts, upon the whole earth.", "ylt": "And now, show not yourselves scorners, Lest strong be your bands, For a consumption, that is determined, I have heard, by the Lord, Jehovah of Hosts, Is for all the land.", "dra": "And now do not mock, lest your bonds be tied strait. For I have heard of the Lord the God of hosts a consumption and a cutting short upon all the earth.", "bbe": "And now, take care that you do not make sport of him, or your bands will be made strong; for I have had word from the Lord, the Lord of armies, of an end, of a complete end, which is to come on all the land.", "geneva": "Nowe therefore be no mockers, least your bondes increase: for I haue heard of the Lord of hostes a consumption, euen determined vpon the whole earth.", "wycliffe": "And now nyle ye scorne, lest perauenture youre boondis be maad streit togidere; for Y herde of the Lord God of oostis, endyng and abreggyng on al erthe.", "rotherham": "Now, therefore do not show yourselves scoffers, Lest your fetters, be bound fast,—For, of a full end, and that a decreed one, have I heard from My Lord, Yahweh of hosts upon all the land", "darby": "Now therefore be ye not scorners, lest your bonds be made strong; for I have heard from the Lord Jehovah of hosts a consumption, and [one] determined, upon the whole land.", "twenty": "", "jps": "Now therefore be ye not scoffers, lest your bands be made strong; for an extermination wholly determined have I heard from the L-rd, the GOD of hosts, upon the whole land.", "acv": "Now therefore be ye not scoffers, lest your bonds be made strong. For I have heard a decree of destruction from the Lord, Jehovah of hosts, upon the whole earth.", "anderson": "", "haweis": "", "noyes": "Now, therefore, be ye no longer scoffers, Lest your bands become stronger; For destruction and punishment have been revealed to me From Jehovah of hosts concerning the whole land!", "webster": "Now therefore be ye not mockers, lest your bands be made strong: for I have heard from the Lord GOD of hosts a consumption, even determined upon the whole earth.", "vulgate": "et nunc nolite inludere ne forte constringantur vincula vestra consummationem enim et adbreviationem audivi a Domino Deo exercituum super universam terram;", "brenton": "Therefore do not ye rejoice, neither let your bands be made strong; for I have heard of works finished and cut short by the Lord of hosts, which he will execute upon all the earth."}}, {"v": 23, "ref": "28:23", "o": "הַאֲזִ֥ינוּ וְ/שִׁמְע֖וּ קוֹלִ֑/י הַקְשִׁ֥יבוּ וְ/שִׁמְע֖וּ אִמְרָתִֽ/י", "en": {"kjv": "Give ye ear, and hear my voice; hearken, and hear my speech.", "web": "Give ear, and hear my voice! Listen, and hear my speech!", "bsb": "Listen and hear my voice. Pay attention and hear what I say.", "asv": "Give ye ear, and hear my voice; hearken, and hear my speech.", "ylt": "Give ear, and hear my voice, Attend, and hear my saying:", "dra": "Give ear, and hear my voice, hearken, and hear my speech.", "bbe": "Let your ears be open to my voice; give attention to what I say.", "geneva": "Hearken ye, and heare my voyce: hearken ye, and heare my speach.", "wycliffe": "Perseyue ye with eeris, and here ye my vois; perseyue ye, and here ye my speche.", "rotherham": "Give ear, and hear ye my voice,—Hearken, and hear ye my speech:—", "darby": "Give ear, and hear my voice; hearken, and hear my speech.", "twenty": "", "jps": "Give ye ear, and hear my voice; attend, and hear my speech.", "acv": "Give ye ear, and hear my voice, hearken, and hear my speech.", "anderson": "", "haweis": "", "noyes": "Give ear, and listen to my voice, Attend, and hearken to my words!", "webster": "Give ye ear, and hear my voice; hearken, and hear my speech.", "vulgate": "auribus percipite et audite vocem meam adtendite et audite eloquium meum;", "brenton": "Hearken, and hear my voice; attend, and hear my words."}}, {"v": 24, "ref": "28:24", "o": "הֲ/כֹ֣ל הַ/יּ֔וֹם יַחֲרֹ֥שׁ הַ/חֹרֵ֖שׁ לִ/זְרֹ֑עַ יְפַתַּ֥ח וִֽ/ישַׂדֵּ֖ד אַדְמָתֽ/וֹ", "en": {"kjv": "Doth the plowman plow all day to sow? doth he open and break the clods of his ground?", "web": "Does he who plows to sow plow continually? Does he keep turning the soil and breaking the clods?", "bsb": "Does the plowman plow for planting every day? Does he continuously loosen and harrow the soil?", "asv": "Doth he that ploweth to sow plow continually? doth he continually open and harrow his ground?", "ylt": "The whole day plougheth the ploughman to sow? He openeth and harroweth his ground!", "dra": "Shall the ploughman plough all the day to sow, shall he open and harrow his ground?", "bbe": "Is the ploughman for ever ploughing? does he not get the earth ready and broken up for the seed?", "geneva": "Doeth the plowe man plowe all the day, to sowe? doeth he open, and breake the clots of his ground?", "wycliffe": "Whether he that erith, schal ere al dai, for to sowe, and schal be kerue, and purge his londe?", "rotherham": "All day long, doth the plowman plow for sowing? Doth he continue laying open and harrowing his soil?", "darby": "Doth the ploughman plough all day to sow? Is he [all day] opening and breaking the clods of his land?", "twenty": "", "jps": "Is the plowman never done with plowing to sow, with the opening and harrowing of his ground?", "acv": "Does he who plows to sow plow continually? Does he continually open and harrow his ground?", "anderson": "", "haweis": "", "noyes": "Is the ploughman always ploughing in order to sow? Is he always opening and harrowing his field?", "webster": "Doth the plowman plow all day to sow? doth he open and break the clods of his ground?", "vulgate": "numquid tota die arabit arans ut serat proscindet et sariet humum suam;", "brenton": "Will the ploughman plough all the day? or will he prepare the seed beforehand, before he tills the ground?"}}, {"v": 25, "ref": "28:25", "o": "הֲ/לוֹא֙ אִם שִׁוָּ֣ה פָנֶ֔י/הָ וְ/הֵפִ֥יץ קֶ֖צַח וְ/כַמֹּ֣ן יִזְרֹ֑ק וְ/שָׂ֨ם חִטָּ֤ה שׂוֹרָה֙ וּ/שְׂעֹרָ֣ה נִסְמָ֔ן וְ/כֻסֶּ֖מֶת גְּבֻלָתֽ/וֹ", "en": {"kjv": "When he hath made plain the face thereof, doth he not cast abroad the fitches, and scatter the cummin, and cast in the principal wheat and the appointed barley and the rie in their place?", "web": "When he has leveled its surface, doesn’t he plant the dill, and scatter the cumin seed, and put in the wheat in rows, the barley in the appointed place, and the spelt in its place?", "bsb": "When he has leveled its surface, does he not sow caraway and scatter cumin? He plants wheat in rows and barley in plots, and rye within its border.", "asv": "When he hath levelled the face thereof, doth he not cast abroad the fitches, and scatter the cummin, and put in the wheat in rows, and the barley in the appointed place, and the spelt in the border thereof?", "ylt": "Hath he not, if he have made level its face, Then scattered fitches, and cummin sprinkle, And hath placed the principal wheat, And the appointed barley, And the rie in its own border?", "dra": "Will he not, when he hath made plain the surface thereof, sow gith, and scatter cummin, and put wheat in order, and barley, and millet, and vetches in their bounds?", "bbe": "When the face of the earth has been levelled, does he not put in the different sorts of seed, and the grain in lines, and the barley in its place, and the spelt at the edge?", "geneva": "When he hath made it plaine, wil he not then sowe the fitches, and sowe cummin, and cast in wheat by measure, and the appointed barly and rye in their place?", "wycliffe": "Whether whanne he hath maad euene the face therof, schal he not sowe gith, and sprenge abrood comyn? and he schal not sette wheete bi ordre, and barli, and mylium, and fetchis in his coostis?", "rotherham": "Doth he not when he hath levelled the face thereof, Cast abroad the fennel? And, the cummin, doth he not scatter? And plant wheat in rows, And barley in a lot, And spelt in the border thereof?", "darby": "Doth he not, when he hath levelled the face thereof, cast abroad dill, and scatter cummin, and set the wheat in rows, and the barley in an appointed place, and the rye in its border?", "twenty": "", "jps": "When he hath made plain the face thereof, doth he not cast abroad the black cummin, and scatter the cummin, and put in the wheat in rows and the barley in the appointed place and the spelt in the border thereof?", "acv": "When he has leveled the face of it, does he not cast abroad the chick-peas, and scatter the cummin, and put in the wheat in rows, and the barley in the appointed place, and the spelt in the border of it?", "anderson": "", "haweis": "", "noyes": "When he hath made the face thereof even, Doth he not then scatter the dill, and cast abroad the cumin, And sow the wheat in rows, And the barley in its appointed place, And the spelt in his border?", "webster": "When he hath made even the face of it, doth he not cast abroad the vetches, and scatter the cummin, and cast in the principal wheat, and the appointed barley, and the rye in their place?", "vulgate": "nonne cum adaequaverit faciem eius seret gith et cyminum sparget et ponet triticum per ordinem et hordeum et milium et viciam in finibus suis;", "brenton": "Does he not, when he has levelled the surface thereof, then sow the small black poppy, or cumin, and afterward sow wheat, and barley, and millet, and bread-corn in thy borders?"}}, {"v": 26, "ref": "28:26", "o": "וְ/יִסְּר֥/וֹ לַ/מִּשְׁפָּ֖ט אֱלֹהָ֥י/ו יוֹרֶֽ/נּוּ", "en": {"kjv": "For his God doth instruct him to discretion, and doth teach him.", "web": "For his God instructs him in right judgment, and teaches him.", "bsb": "For his God instructs and teaches him properly.", "asv": "For his God doth instruct him aright, and doth teach him.", "ylt": "And instruct him for judgment doth his God, He doth direct him.", "dra": "For he will instruct him in judgment: his God will teach him.", "bbe": "For his God is his teacher, giving him the knowledge of these things.", "geneva": "For his God doeth instruct him to haue discretion, and doeth teach him.", "wycliffe": "And his God schal teche hym, in doom he schal teche hym.", "rotherham": "Yea One hath trained him to good judgment, His God, directeth him.", "darby": "HisGod doth instruct him in [his] judgment, he doth teach him.", "twenty": "", "jps": "For He doth instruct him aright; his G-d doth teach him.", "acv": "For his God instructs him aright, and teaches him.", "anderson": "", "haweis": "", "noyes": "Thus his God rightly instructeth him, And giveth him knowledge.", "webster": "For his God doth instruct him to discretion, [and] doth teach him.", "vulgate": "et erudiet eum illud in iudicio Deus suus docebit eum illud;", "brenton": "So thou shalt be chastened by the judgment of thy God, and shalt rejoice."}}, {"v": 27, "ref": "28:27", "o": "כִּ֣י לֹ֤א בֶֽ/חָרוּץ֙ י֣וּדַשׁ קֶ֔צַח וְ/אוֹפַ֣ן עֲגָלָ֔ה עַל כַּמֹּ֖ן יוּסָּ֑ב כִּ֧י בַ/מַּטֶּ֛ה יֵחָ֥בֶט קֶ֖צַח וְ/כַמֹּ֥ן בַּ/שָּֽׁבֶט", "en": {"kjv": "For the fitches are not threshed with a threshing instrument, neither is a cart wheel turned about upon the cummin; but the fitches are beaten out with a staff, and the cummin with a rod.", "web": "For the dill are not threshed with a sharp instrument, neither is a cart wheel turned over the cumin; but the dill is beaten out with a stick, and the cumin with a rod.", "bsb": "Surely caraway is not threshed with a sledge, and the wheel of a cart is not rolled over the cumin. But caraway is beaten out with a stick, and cumin with a rod.", "asv": "For the fitches are not threshed with a sharp threshing instrument, neither is a cart wheel turned about upon the cummin; but the fitches are beaten out with a staff, and the cummin with a rod.", "ylt": "For not with a sharp-pointed thing threshed are fitches, And the wheel of a cart on cummin turned round, For with a staff beaten out are fitches, And cummin with a rod.", "dra": "For gith shall not be thrashed with saws, neither shall the cart wheel turn about upon cummin: but gith shall be beaten out with a rod, and cumin with a staff.", "bbe": "For the fitches are not crushed with a sharp instrument, and a cart-wheel is not rolled over the cummin; but the grain of the fitches is hammered out with a stick, and of the cummin with a rod.", "geneva": "For fitches shall not be threshed with a threshing instrument, neither shall a cart wheele be turned about vpon the cummin: but ye fitches are beaten out with a staffe, and cummin with a rod.", "wycliffe": "Forsothe gith schal not be threischid in sawis, and a wheel of a wayn schal not cumpasse on comyn; but gith schal be betun out with a yerd, and comyn with a staf.", "rotherham": "For not with a sledge, must, black coriander be threshed, Nor must, the wheel of a cart, on cummin, be turned, But with a staff, must fennel be beaten, And cummin with a rod:", "darby": "For the dill is not threshed with a threshing instrument, neither is a cart-wheel turned about upon the cummin; but dill is beaten out with a staff, and cummin with a rod.", "twenty": "", "jps": "For the black cummin is not threshed with a threshing-sledge, neither is a cart-wheel turned about upon the cummin; but the black cummin is beaten out with a staff, and the cummin with a rod.", "acv": "For the chick-peas are not threshed with a sharp instrument, nor is a cart wheel turned about upon the cummin, but the chick-peas are beaten out with a staff, and the cummin with a rod.", "anderson": "", "haweis": "", "noyes": "The dill is not beaten out with the thrashing-sledge, Nor is the wheel of the wain rolled over the cumin; But the dill is beaten out with a staff, And the cumin with a rod.", "webster": "For the vetches are not threshed with a threshing instrument, neither is a cart-wheel turned about upon the cummin; but the vetches are beaten out with a staff, and the cummin with a rod.", "vulgate": "non enim in serris triturabitur gith nec rota plaustri super cyminum circumiet sed in virga excutietur gith et cyminum in baculo;", "brenton": "For the black poppy is not cleansed with harsh treatment, nor will a wagon-wheel pass over the cumin; but the black poppy is threshed with a rod, and the cumin shall be eaten with bread;"}}, {"v": 28, "ref": "28:28", "o": "לֶ֣חֶם יוּדָ֔ק כִּ֛י לֹ֥א לָ/נֶ֖צַח אָד֣וֹשׁ יְדוּשֶׁ֑/נּוּ וְ֠/הָמַם גִּלְגַּ֧ל עֶגְלָת֛/וֹ וּ/פָרָשָׁ֖י/ו לֹֽא יְדֻקֶּֽ/נּוּ", "en": {"kjv": "Bread corn is bruised; because he will not ever be threshing it, nor break it with the wheel of his cart, nor bruise it with his horsemen.", "web": "Bread flour must be ground; so he will not always be threshing it. Although he drives the wheel of his threshing cart over it, his horses don’t grind it.", "bsb": "Grain for bread must be ground, but it is not endlessly threshed. Though the wheels of the cart roll over it, the horses do not crush it.", "asv": "Bread grain is ground; for he will not be always threshing it: and though the wheel of his cart and his horses scatter it, he doth not grind it.", "ylt": "Bread- corn is beaten small, For not for ever doth he sorely thresh it, Nor crushed it hath a wheel of his cart, Nor do his hoofs beat it small.", "dra": "But breadcorn shall be broken small: but the thrasher shall not thrash it for ever, neither shall the cart wheel hurt it, nor break it with its teeth.", "bbe": "Is the grain for bread crushed? He does not go on crushing it for ever, but he lets his cart-wheels and his horses go over it without crushing it.", "geneva": "Bread corne when it is threshed, hee doeth not alway thresh it, neither doeth the wheele of his cart still make a noyse, neither will he breake it with the teeth thereof.", "wycliffe": "Sotheli breed schal be maad lesse, but he that threischith schal not threische it with outen ende, nether schal trauele it with a wheel of a wayn, nether schal make it lesse with hise clees.", "rotherham": "Bread-corn, must be crushed,—Yet would he not be evermore, threshing, it, So he hasteneth over it the wheel of his cart, with his horsemen, He crusheth it not!", "darby": "Bread [corn] is crushed, because he will not ever be threshing it; and if he drove the wheels of his cart and his horses [over it], he would not crush it.", "twenty": "", "jps": "Is bread corn crushed? Nay, he will not ever be threshing it; and though the roller of his wagon and its sharp edges move noisily, he doth not crush it.", "acv": "Bread grain is ground, for he will not be always threshing it. And though the wheel of his cart and his horses scatter it, he does not grind it.", "anderson": "", "haweis": "", "noyes": "Bread-corn is beaten out, Yet doth not the husbandman thrash it without limit. He driveth over it the wheels of the wain, And the horses, yet doth he not utterly crush it.", "webster": "Bread-[corn] is bruised; because he will not always be threshing it, nor break [it with] the wheel of his cart, nor bruise it [with] his horsemen.", "vulgate": "panis autem comminuetur verum non in perpetuum triturans triturabit illum neque vexabit eum rota plaustri nec in ungulis suis comminuet eum;", "brenton": "for I will not be wroth with you for ever, neither shall the voice of my anger crush you."}}, {"v": 29, "ref": "28:29", "o": "גַּם זֹ֕את מֵ/עִ֛ם יְהוָ֥ה צְבָא֖וֹת יָצָ֑אָה הִפְלִ֣יא עֵצָ֔ה הִגְדִּ֖יל תּוּשִׁיָּֽה", "en": {"kjv": "This also cometh forth from the Lord of hosts, which is wonderful in counsel, and excellent in working.", "web": "This also comes out from Yahweh of Armies, who is wonderful in counsel, and excellent in wisdom.", "bsb": "This also comes from the LORD of Hosts, who is wonderful in counsel and excellent in wisdom.", "asv": "This also cometh forth from Jehovah of hosts, who is wonderful in counsel, and excellent in wisdom.", "ylt": "Even this from Jehovah of Hosts hath gone out, He hath made counsel wonderful, He hath made wisdom great!", "dra": "This also is come forth from the Lord God of hosts, to make his counsel wonderful, and magnify justice.", "bbe": "This comes from the Lord of armies, purposing wonders, and wise in all his acts.", "geneva": "This also commeth from the Lord of hostes, which is wonderfull in counsell, and excellent in workes.", "wycliffe": "And this thing yede out of the Lord God of oostis, that he schulde make wondirful councel, and magnefie riytfulnesse.", "rotherham": "Even this, from Yahweh of hosts, cometh forth,—Who hath bestowed distinction upon counsel, And magnified sound wisdom.", "darby": "This also cometh forth from Jehovah of hosts; he is wonderful in counsel, great in wisdom.", "twenty": "", "jps": "This also cometh forth from HaShem of hosts: Wonderful is His counsel, and great His wisdom.", "acv": "This also comes forth from Jehovah of hosts, who is wonderful in counsel, and excellent in wisdom.", "anderson": "", "haweis": "", "noyes": "This also proceedeth from Jehovah of hosts; He is wonderful in counsel, Excellent in wisdom.", "webster": "This also cometh forth from the LORD of hosts, [who] is wonderful in counsel, [and] excellent in operation.", "vulgate": "et hoc a Domino Deo exercituum exivit ut mirabile faceret consilium et magnificaret iustitiam;", "brenton": "And these signs came forth from the Lord of hosts. Take counsel, exalt vain comfort."}}]}, {"c": 29, "verses": [{"v": 1, "ref": "29:1", "o": "ה֚וֹי אֲרִיאֵ֣ל אֲרִיאֵ֔ל קִרְיַ֖ת חָנָ֣ה דָוִ֑ד סְפ֥וּ שָׁנָ֛ה עַל שָׁנָ֖ה חַגִּ֥ים יִנְקֹֽפוּ", "en": {"kjv": "Woe to Ariel, to Ariel, the city where David dwelt! add ye year to year; let them kill sacrifices.", "web": "Woe to Ariel! Ariel, the city where David encamped! Add year to year; let the feasts come around;", "bsb": "Woe to you, O Ariel, the city of Ariel where David camped! Year upon year let your festivals recur.", "asv": "Ho Ariel, Ariel, the city where David encamped! add ye year to year; let the feasts come round:", "ylt": "Woe to Ariel, Ariel, The city of the encampment of David! Add year to year, let festivals go round.", "dra": "Woe to Ariel, to Ariel the city which David took: year is added to year. the solemnities are at an end.", "bbe": "Ho! Ariel, Ariel, the town against which David made war; put year to year, let the feasts come round:", "geneva": "Ah altar, altar of the citie that Dauid dwelt in: adde yere vnto yere: let them kill lambs.", "wycliffe": "Wo! Ariel, Ariel, the citee which Dauid ouercam; yeer is addid to yeer, solempnytees ben passyd.", "rotherham": "Alas for Ariel, Ariel, The city against which, David encamped,—Add ye a year to a year. Let the festivals, come round;", "darby": "Woe to Ariel, to Ariel, the city of David's encampment! Add ye year to year; let the feasts come round.", "twenty": "", "jps": "Ah, Ariel, Ariel, the city where David encamped! Add ye year to year, let the feasts come round!", "acv": "Ho Ariel, Ariel, the city where David encamped! Add ye year to year. Let the feasts come round.", "anderson": "", "haweis": "", "noyes": "Woe to Ariel, to Ariel, The city where David dwelt! Add year to year, Let the festivals go round,", "webster": "Woe to Ariel, to Ariel, the city [where] David dwelt! add ye year to year; let them kill sacrifices.", "vulgate": "vae Arihel Arihel civitas quam circumdedit David additus est annus ad annum sollemnitates evolutae sunt;", "brenton": "Alas for the city of Ariel, which David besieged. Gather ye fruits year by year; eat ye, for ye shall eat with Moab."}}, {"v": 2, "ref": "29:2", "o": "וַ/הֲצִיק֖וֹתִי לַֽ/אֲרִיאֵ֑ל וְ/הָיְתָ֤ה תַֽאֲנִיָּה֙ וַֽ/אֲנִיָּ֔ה וְ/הָ֥יְתָה לִּ֖/י כַּ/אֲרִיאֵֽל", "en": {"kjv": "Yet I will distress Ariel, and there shall be heaviness and sorrow: and it shall be unto me as Ariel.", "web": "then I will distress Ariel, and there will be mourning and lamentation. She shall be to me as an altar hearth.", "bsb": "And I will constrain Ariel, and there will be mourning and lamentation; she will be like an altar hearth before Me.", "asv": "then will I distress Ariel, and there shall be mourning and lamentation; and she shall be unto me as Ariel.", "ylt": "And I have sent distress to Ariel, And it hath been lamentation and mourning, And it hath been to me as Ariel.", "dra": "And I will make a trench about Ariel, and it shall be in sorrow and mourning, and it shall be to me as Ariel.", "bbe": "And I will send trouble on Ariel, and there will be weeping and cries of grief; and she will be to me as Ariel.", "geneva": "But I wil bring the altar into distresse, and there shalbe heauines and sorowe, and it shall be vnto me like an altar.", "wycliffe": "And Y schal cumpasse Ariel, and it schal be soreuful and morenynge; and Jerusalem schal be to me as Ariel.", "rotherham": "Yet will I bring Ariel into straits,—And she shall become a bewailing and wailing, Yea she shall become to me a veritable Hearth of God.", "darby": "But I will distress Ariel, and there shall be sorrow and sadness; and it shall be unto me as an Ariel.", "twenty": "", "jps": "Then will I distress Ariel, and there shall be mourning and moaning; and she shall be unto Me as a hearth of G-d.", "acv": "Then I will distress Ariel, and there shall be mourning and lamentation, and she shall be to me as Ariel.", "anderson": "", "haweis": "", "noyes": "Then will I distress Ariel; Mourning and sorrow shall be there; Yet shall she be to me as Ariel [the lion of God].", "webster": "Yet I will distress Ariel, and there shall be heaviness and sorrow; and it shall be to me as Ariel.", "vulgate": "et circumvallabo Arihel et erit tristis et maerens et erit mihi quasi Arihel;", "brenton": "For I will grievously afflict Ariel: and her strength and her wealth shall be mine."}}, {"v": 3, "ref": "29:3", "o": "וְ/חָנִ֥יתִי כַ/דּ֖וּר עָלָ֑יִ/ךְ וְ/צַרְתִּ֤י עָלַ֨יִ/ךְ֙ מֻצָּ֔ב וַ/הֲקִֽימֹתִ֥י עָלַ֖יִ/ךְ מְצֻרֹֽת", "en": {"kjv": "And I will camp against thee round about, and will lay siege against thee with a mount, and I will raise forts against thee.", "web": "I will encamp against you all around you, and will lay siege against you with posted troops. I will raise siege works against you.", "bsb": "I will camp in a circle around you; I will besiege you with towers and set up siege works against you.", "asv": "And I will encamp against thee round about, and will lay siege against thee with posted troops, and I will raise siege works against thee.", "ylt": "And I encamped, O babbler, against thee, And I laid siege against thee--a camp. And I raised up against thee bulwarks.", "dra": "And I will make a circle round about thee, and I will cast up a rampart against thee, and raise up bulwarks to besiege thee.", "bbe": "And I will make war on you like David, and you will be shut in by earthworks, and I will make towers round you.", "geneva": "And I wil besiege thee as a circle, and fight against thee on a mount, and will cast vp ramparts against thee.", "wycliffe": "And Y schal cumpasse as a round trendil in thi cumpasse, and Y schal caste erthe ayens thee, and Y schal sette engynes in to thi bisegyng.", "rotherham": "And I will encamp round about against thee,—And lay siege against thee with a fort, And raise against thee siege-works;", "darby": "And I will camp against thee round about, and will lay siege against thee with watch-posts, and I will raise forts against thee.", "twenty": "", "jps": "And I will encamp against thee round about, and will lay siege against thee with a mound, and I will raise siege works against thee.", "acv": "And I will encamp against thee round about, and will lay siege against thee with posted troops. And I will raise siege works against thee.", "anderson": "", "haweis": "", "noyes": "I will encamp against thee round about, And I will lay siege against thee with a mound, And I will raise towers against thee.", "webster": "And I will encamp against thee round about, and will lay siege against thee with a mount, and I will raise forts against thee.", "vulgate": "et circumdabo quasi spheram in circuitu tuo et iaciam contra te aggerem et munimenta ponam in obsidionem tuam;", "brenton": "And I will compass thee about like David, and will raise a mound about thee, and set up towers round thee."}}, {"v": 4, "ref": "29:4", "o": "וְ/שָׁפַלְתְּ֙ מֵ/אֶ֣רֶץ תְּדַבֵּ֔רִי וּ/מֵֽ/עָפָ֖ר תִּשַּׁ֣ח אִמְרָתֵ֑/ךְ וְֽ֠/הָיָה כְּ/א֤וֹב מֵ/אֶ֨רֶץ֙ קוֹלֵ֔/ךְ וּ/מֵ/עָפָ֖ר אִמְרָתֵ֥/ךְ תְּצַפְצֵֽף", "en": {"kjv": "And thou shalt be brought down, and shalt speak out of the ground, and thy speech shall be low out of the dust, and thy voice shall be, as of one that hath a familiar spirit, out of the ground, and thy speech shall whisper out of the dust.", "web": "You will be brought down, and will speak out of the ground. Your speech will mumble out of the dust. Your voice will be as of one who has a familiar spirit, out of the ground, and your speech will whisper out of the dust.", "bsb": "You will be brought low, you will speak from the ground, and out of the dust your words will be muffled. Your voice will be like a spirit from the ground; your speech will whisper out of the dust.", "asv": "And thou shalt be brought down, and shalt speak out of the ground, and thy speech shall be low out of the dust; and thy voice shall be as of one that hath a familiar spirit, out of the ground, and thy speech shall whisper out of the dust.", "ylt": "And thou hast been low, From the earth thou speakest, And from the dust makest thy saying low, And thy voice hath been from the earth, As one having a familiar spirit, And from the dust thy saying whisperest,", "dra": "Thou shalt be brought down, thou shall speak out of the earth, and thy speech shall be heard out of the ground: and thy voice shall be from the earth like that of the python, and out of the earth thy speech shall mutter.", "bbe": "And you will be made low, and your voice will come out of the earth, and your words will be low out of the dust; and your voice will come out of the earth like that of a spirit, making bird-like noises out of the dust.", "geneva": "So shalt thou be humbled, and shalt speake out of the ground, and thy speach shalbe as out of the dust: thy voyce also shall be out of the ground like him that hath a spirite of diuination, and thy talking shall whisper out of the dust.", "wycliffe": "Thou schalt be maad low, thou schalt speke of erthe, and thi speche schal be herd fro the erthe; and thi vois schal be as the vois of a deed man reisid bi coniuring, and thi speche schal ofte grutche of the erthe.", "rotherham": "And thou shalt be brought low—Out of the earth, shalt thou speak, And out of the dust, shalt thou lower thine utterance,—And as one that hath a familiar spirit, Out of the earth, shall come thy voice, And out of the dust, thy speech shall chirp;", "darby": "And thou shalt be brought low, thou shalt speak out of the ground, and thy speech shall come low out of the dust, and thy voice shall be as of one that hath a familiar spirit, out of the ground, and thy speech shall whisper out of the dust.", "twenty": "", "jps": "And brought down thou shalt speak out of the ground, and thy speech shall be low out of the dust; and thy voice shall be as of a ghost out of the ground, and thy speech shall chirp out of the dust.", "acv": "And thou shall be brought down, and shall speak out of the ground. And thy speech shall be low out of the dust, and thy voice shall be as of he who has a familiar spirit, out of the ground. And thy speech shall whisper out of the dust.", "anderson": "", "haweis": "", "noyes": "Thou shalt be brought down, and speak from the ground, And thy speech shall be low from the dust; Thy voice shall be like that of a spirit under ground, And thy speech shall chirp as from the dust.", "webster": "And thou shalt be brought down, [and] shalt speak out of the ground, and thy speech shall be low out of the dust, and thy voice shall be, as of one that hath a familiar spirit, out of the ground, and thy speech shall whisper out of the dust.", "vulgate": "humiliaberis de terra loqueris et de humo audietur eloquium tuum et erit quasi pythonis de terra vox tua et de humo eloquium tuum mussitabit;", "brenton": "And thy words shall be brought down to the earth, and thy words shall sink down to the earth, and thy voice shall be as they that speak out of the earth, and thy voice shall be lowered to the ground."}}, {"v": 5, "ref": "29:5", "o": "וְ/הָיָ֛ה כְּ/אָבָ֥ק דַּ֖ק הֲמ֣וֹן זָרָ֑יִ/ךְ וּ/כְ/מֹ֤ץ עֹבֵר֙ הֲמ֣וֹן עָֽרִיצִ֔ים וְ/הָיָ֖ה לְ/פֶ֥תַע פִּתְאֹֽם", "en": {"kjv": "Moreover the multitude of thy strangers shall be like small dust, and the multitude of the terrible ones shall be as chaff that passeth away: yea, it shall be at an instant suddenly.", "web": "But the multitude of your foes will be like fine dust, and the multitude of the ruthless ones like chaff that blows away. Yes, it will be in an instant, suddenly.", "bsb": "But your many foes will be like fine dust, the multitude of the ruthless like blowing chaff. Then suddenly, in an instant,", "asv": "But the multitude of thy foes shall be like small dust, and the multitude of the terrible ones as chaff that passeth away: yea, it shall be in an instant suddenly.", "ylt": "And as small dust hath been The multitude of those scattering thee, And as chaff passing on the multitude of the terrible, And it hath been at an instant--suddenly.", "dra": "And the multitude of them that fan thee, shall be like small dust: and as ashes passing away, the multitude of them that have prevailed against thee.", "bbe": "And the army of your attackers will be like small dust, and all the cruel ones like dry stems gone before the wind; suddenly it will come about.", "geneva": "Moreouer, the multitude of thy strangers shalbe like small dust, and the multitude of strong men shalbe as chaffe that passeth away, and it shall be in a moment, euen suddenly.", "wycliffe": "And the multitude of hem that wyndewen thee, schal be as thynne dust; and the multitude of hem that hadden the maistrie ayens thee, schal be as a deed sparcle passynge.", "rotherham": "Then shall be as fine dust the multitude of thy foreigners,—And as chaff that passeth away, the multitude of tyrants; And it shall come to pass, in a twinkling, Suddenly,", "darby": "And the multitude of thine enemies shall be like small dust, and the multitude of the terrible ones as chaff that passeth away; and it shall be in an instant, suddenly.", "twenty": "", "jps": "But the multitude of thy foes shall be like small dust, and the multitude of the terrible ones as chaff that passeth away; yea, it shall be at an instant suddenly--", "acv": "But the multitude of thy foes shall be like small dust, and the multitude of the terrible ones as chaff that passes away. Yea, it shall be in an instant suddenly.", "anderson": "", "haweis": "", "noyes": "Yet shall the multitude of thine enemies be like fine dust; The multitude of the terrible like flying chaff; It shall take place suddenly, in a moment.", "webster": "Moreover, the multitude of thy strangers shall be like small dust, and the multitude of the terrible ones [shall be] as chaff that passeth away: yes, it shall be at an instant suddenly.", "vulgate": "et erit sicut pulvis tenuis multitudo ventilantium te et sicut favilla pertransiens multitudo eorum qui contra te praevaluerunt;", "brenton": "But the wealth of the ungodly shall be as dust from a wheel, and the multitude of them that oppress thee as flying chaff, and it shall be suddenly as a moment,"}}, {"v": 6, "ref": "29:6", "o": "מֵ/עִ֨ם יְהוָ֤ה צְבָאוֹת֙ תִּפָּקֵ֔ד בְּ/רַ֥עַם וּ/בְ/רַ֖עַשׁ וְ/ק֣וֹל גָּד֑וֹל סוּפָה֙ וּ/סְעָרָ֔ה וְ/לַ֖הַב אֵ֥שׁ אוֹכֵלָֽה", "en": {"kjv": "Thou shalt be visited of the Lord of hosts with thunder, and with earthquake, and great noise, with storm and tempest, and the flame of devouring fire.", "web": "She will be visited by Yahweh of Armies with thunder, with earthquake, with great noise, with whirlwind and storm, and with the flame of a devouring fire.", "bsb": "you will be visited by the LORD of Hosts with thunder and earthquake and loud noise, with windstorm and tempest and consuming flame of fire.", "asv": "She shall be visited of Jehovah of hosts with thunder, and with earthquake, and great noise, with whirlwind and tempest, and the flame of a devouring fire.", "ylt": "By Jehovah of Hosts thou art inspected, With thunder, and with an earthquake, And great noise, hurricane, and whirlwind, And flame of devouring fire.", "dra": "And it shall be at an instant suddenly. A visitation shall come from the Lord of hosts in thunder, and with earthquake, and with a great noise of whirlwind and tempest; and with the flame of devouring fire.", "bbe": "The Lord of armies will come in with thunder and earth-shaking and great noise, with rushing wind and storm, and the flame of burning fire.", "geneva": "Thou shalt be visited of the Lord of hostes with thunder, and shaking, and a great noyse, a whirlewinde, and a tempest, and a flame of a deuouring fire.", "wycliffe": "And it schal be sudenli, anoon it schal be visitid of the Lord of oostis, in thundur, and in mouyng of the erthe, and in greet vois of whirlwynd, and of tempest, and of flawme of fier deuowrynge.", "rotherham": "From Yahweh of hosts, shalt thou be visited, With thunder, and with earthquake and a great noise, hurricane and storm and flame of fire devouring;", "darby": "Thou shalt be visited by Jehovah of hosts with thunder and with earthquake and great noise, with whirlwind and tempest, and the flame of devouring fire.", "twenty": "", "jps": "There shall be a visitation from HaShem of hosts with thunder, and with earthquake, and great noise, with whirlwind and tempest, and the flame of a devouring fire.", "acv": "She shall be visited by Jehovah of hosts with thunder, and with earthquake, and great noise, with whirlwind and tempest, and the flame of a devouring fire.", "anderson": "", "haweis": "", "noyes": "From Jehovah of hosts cometh the visitation With thunder, and earthquake, and great noise, With storm and tempest, And flames of devouring fire.", "webster": "Thou shalt be visited by the LORD of hosts with thunder, and with earthquake, and great noise, with storm and tempest, and the flame of devouring fire.", "vulgate": "eritque repente confestim a Domino exercituum visitabitur in tonitru et commotione terrae et voce magna turbinis et tempestatis et flammae ignis devorantis;", "brenton": "from the Lord of Hosts: for there shall be a visitation with thunder, and earthquake, and a loud noise, a rushing tempest, and devouring flame of fire."}}, {"v": 7, "ref": "29:7", "o": "וְ/הָיָ֗ה כַּֽ/חֲלוֹם֙ חֲז֣וֹן לַ֔יְלָה הֲמוֹן֙ כָּל הַ/גּוֹיִ֔ם הַ/צֹּבְאִ֖ים עַל אֲרִיאֵ֑ל וְ/כָל צֹבֶ֨י/הָ֙ וּ/מְצֹ֣דָתָ֔/הּ וְ/הַ/מְּצִיקִ֖ים לָֽ/הּ", "en": {"kjv": "And the multitude of all the nations that fight against Ariel, even all that fight against her and her munition, and that distress her, shall be as a dream of a night vision.", "web": "The multitude of all the nations that fight against Ariel, even all who fight against her and her stronghold, and who distress her, will be like a dream, a vision of the night.", "bsb": "All the many nations going out to battle against Ariel— even all who war against her, laying siege and attacking her— will be like a dream, like a vision in the night,", "asv": "And the multitude of all the nations that fight against Ariel, even all that fight against her and her stronghold, and that distress her, shall be as a dream, a vision of the night.", "ylt": "And as a dream, a vision of night, hath been The multitude of all the nations Who are warring against Ariel, And all its warriors, and its bulwark, Even of those distressing her.", "dra": "And the multitude of all nations that have fought against Ariel, shall be as the dream of a vision by night, and all that have fought, and besieged and prevailed against it.", "bbe": "And all the nations making war on Ariel, and all those who are fighting against her and shutting her in with their towers, will be like a dream, like a vision of the night.", "geneva": "And the multitude of all the nations that fight against the altar, shalbe as a dreame or vision by night: euen all they that make the warre against it, and strong holdes against it, and lay siege vnto it.", "wycliffe": "And the multitude of alle folkis that fouyten ayens Ariel schal be as the dreem of a nyytis visioun; and alle men that fouyten, and bisegiden, and hadden the maistrie ayens it.", "rotherham": "And it shall be like the dream of a night vision, With the multitude of all the nations who have been making war against Ariel,—Even with all who have been making war against her and her stronghold and who have been laying siege to her;", "darby": "And the multitude of all the nations that war against Ariel, even all that war against her and her fortifications, and that distress her, shall be as a dream of a night vision.", "twenty": "", "jps": "And the multitude of all the nations that war against Ariel, even all that war against her, and the bulwarks about her, and they that distress her, shall be as a dream, a vision of the night.", "acv": "And the multitude of all the nations that fight against Ariel, even all that fight against her and her stronghold, and that distress her, shall be as a dream, a vision of the night.", "anderson": "", "haweis": "", "noyes": "As a dream, a vision of the night, Shall be the multitude of all the nations That fight against Ariel, That fight against her and her fortress, And distress her.", "webster": "And the multitude of all the nations that fight against Ariel, even all that fight against her and her munition, and that distress her, shall be as a dream of a night-vision.", "vulgate": "et erit sicut somnium visionis nocturnae multitudo omnium gentium quae dimicaverunt contra Arihel et omnes qui militaverunt et obsederunt et praevaluerunt adversus eam;", "brenton": "And the wealth of all the nations together, as many as have fought against Ariel, and all they that war against Jerusalem, and all who are gathered against her, and they that distress her, shall be as one that dreams in sleep by night."}}, {"v": 8, "ref": "29:8", "o": "וְ/הָיָ֡ה כַּ/אֲשֶׁר֩ יַחֲלֹ֨ם הָ/רָעֵ֜ב וְ/הִנֵּ֣ה אוֹכֵ֗ל וְ/הֵקִיץ֮ וְ/רֵיקָ֣ה נַפְשׁ/וֹ֒ וְ/כַ/אֲשֶׁ֨ר יַחֲלֹ֤ם הַ/צָּמֵא֙ וְ/הִנֵּ֣ה שֹׁתֶ֔ה וְ/הֵקִיץ֙ וְ/הִנֵּ֣ה עָיֵ֔ף וְ/נַפְשׁ֖/וֹ שׁוֹקֵקָ֑ה כֵּ֣ן יִֽהְיֶ֗ה הֲמוֹן֙ כָּל הַ/גּוֹיִ֔ם הַ/צֹּבְאִ֖ים עַל הַ֥ר צִיּֽוֹן", "en": {"kjv": "It shall even be as when an hungry man dreameth, and, behold, he eateth; but he awaketh, and his soul is empty: or as when a thirsty man dreameth, and, behold, he drinketh; but he awaketh, and, behold, he is faint, and his soul hath appetite: so shall the multitude of all the nations be, that fight against mount Zion.", "web": "It will be like when a hungry man dreams, and behold, he eats; but he awakes, and his hunger isn’t satisfied; or like when a thirsty man dreams, and behold, he drinks; but he awakes, and behold, he is faint, and he is still thirsty. The multitude of all the nations that fight against Mount Zion will be like that.", "bsb": "as when a hungry man dreams he is eating, then awakens still hungry; as when a thirsty man dreams he is drinking, then awakens faint and parched. So will it be for all the many nations who go to battle against Mount Zion.", "asv": "And it shall be as when a hungry man dreameth, and, behold, he eateth; but he awaketh, and his soul is empty: or as when a thirsty man dreameth, and, behold, he drinketh; but he awaketh, and, behold, he is faint, and his soul hath appetite: so shall the multitude of all the nations be, that fight against mount Zion.", "ylt": "And it hath been, as when the hungry dreameth, And lo, he is eating, And he hath waked, and empty is his soul, And as when the thirsty dreameth, And lo, he is drinking, and he hath waked, And lo, he is weary, and his soul is longing, So is the multitude of all the nations Who are warring against mount Zion.", "dra": "And as he that is hungry dreameth, and eateth, but when he is awake, his soul is empty: and as he that is thirsty dreameth, and drinketh and after he is awake, is yet faint with thirst, and his soul is empty: so shall be the multitude of all the Gentiles, that have fought against mount Sion.", "bbe": "And it will be like a man desiring food, and dreaming that he is feasting; but when he is awake there is nothing in his mouth: or like a man in need of water, dreaming that he is drinking; but when he is awake he is feeble and his soul is full of desire: so will all the nations be which make war on Mount Zion.", "geneva": "And it shalbe like as an hungry man dreameth, and beholde, he eateth: and when he awaketh, his soule is emptie: or like as a thirsty man dreameth, and loe, he is drinking, and when he awaketh, beholde, he is faint, and his soule longeth: so shall the multitude of all nations be that fight against mount Zion.", "wycliffe": "And as an hungry man dremyth, and etith, but whanne he is awakid, his soule is voide; and as a thirsti man dremeth, and drynkith, and after that he is awakid, he is weri, and thirstith yit, and his soule is voide, so schal be the multitude of alle folkis, that fouyten ayens the hil of Sion.", "rotherham": "Yea it shall be As when the hungry man dreameth and lo! he is eating, But he awaketh, and his soul, is empty, Or as when the thirsty man dreameth and lo! he is drinking, But he awaketh and lo! he is faint and his soul, is craving, So, shall it be with the multitude of all the nations, that have come forth to war against Mount Zion.", "darby": "It shall even be as when the hungry dreameth, and, behold, he eateth; and he awaketh, and his soul is empty; or as when the thirsty dreameth, and, behold, he drinketh; and he awaketh, and, behold, he is faint, and his soul craveth: so shall the multitude of all the nations be that war against mount Zion.", "twenty": "", "jps": "And it shall be as when a hungry man dreameth, and, behold, he eateth, but he awaketh, and his soul is empty; or as when a thirsty man dreameth, and, behold, he drinketh, but he awaketh, and, behold, he is faint, and his soul hath appetite--so shall the multitude of all the nations be, that fight against mount Zion.", "acv": "And it shall be as when a hungry man dreams, and, behold, he eats. But he awakes, and his soul is empty. Or as when a thirsty man dreams, and, behold, he drinks. But he awakes, and, behold, he is faint, and his soul has appetite. So shall the multitude of all the nations be that fight against mount Zion.", "anderson": "", "haweis": "", "noyes": "As a hungry man dreameth, and lo! he eateth, But awaketh and is still hungry; And as a thirsty man dreameth, and lo! he drinketh, But awaketh, and lo! he is faint and thirsty; So shall it be with the multitude of all the nations That fight against mount Zion.", "webster": "It shall even be as when a hungry [man] dreameth, and behold, he eateth; but he awaketh, and his soul is empty: or as when a thirsty man dreameth, and behold, he drinketh; but he awaketh, and behold, [he is] faint, and his soul hath appetite: so shall the multitude of all the nations be, that fight against mount Zion.", "vulgate": "et sicuti somniat esuriens et comedit cum autem fuerit expertus vacua est anima eius et sicut somniat sitiens et bibit et postquam fuerit expergefactus lassus adhuc sitit et anima eius vacua est sic erit multitudo omnium gentium quae dimicaverunt contra montem Sion;", "brenton": "And as men drink and eat in sleep, and when they have arisen, the dream is vain: and as a thirsty man dreams as if he drank, and having arisen is still thirsty, and his soul has desired in vain: so shall be the wealth of all the nations, as many as have fought against the mount Sion."}}, {"v": 9, "ref": "29:9", "o": "הִתְמַהְמְה֣וּ וּ/תְמָ֔הוּ הִשְׁתַּֽעַשְׁע֖וּ וָ/שֹׁ֑עוּ שָֽׁכְר֣וּ וְ/לֹא יַ֔יִן נָע֖וּ וְ/לֹ֥א שֵׁכָֽר", "en": {"kjv": "Stay yourselves, and wonder; cry ye out, and cry: they are drunken, but not with wine; they stagger, but not with strong drink.", "web": "Pause and wonder! Blind yourselves and be blind! They are drunken, but not with wine; they stagger, but not with strong drink.", "bsb": "Stop and be astonished; blind yourselves and be sightless; be drunk, but not with wine; stagger, but not from strong drink.", "asv": "Tarry ye and wonder; take your pleasure and be blind: they are drunken, but not with wine; they stagger, but not with strong drink.", "ylt": "Tarry and wonder, look ye, yea, look, Be drunk, and not with wine, Stagger, and not with strong drink.", "dra": "Be astonished, and wonder, waver, and stagger: be drunk, and not with wine: stagger, and not with drunkenness.", "bbe": "Be surprised and full of wonder; let your eyes be covered and be blind: be overcome, but not with wine; go with uncertain steps, but not because of strong drink.", "geneva": "Stay your selues, and wonder: they are blinde, and make you blinde: they are drunken but not with wine: they stagger, but not by strong drinke.", "wycliffe": "Be ye astonyed, and wondre; wake ye, and douyte ye; be ye drunken, and not of wyn; be ye moued, and not with drunkenesse.", "rotherham": "Stand ye stock still and stare, Besmear your eyes and be blind,—They are drunken but not with wine, They reel, but not with strong drink;", "darby": "Be astounded and astonished, blind yourselves and be blind! They are drunken, but not with wine; they stagger, but not with strong drink.", "twenty": "", "jps": "Stupefy yourselves, and be stupid! Blind yourselves, and be blind! ye that are drunken, but not with wine, that stagger, but not with strong drink.", "acv": "Tarry ye and wonder, take your pleasure and be blind. They are drunken, but not with wine. They stagger, but not with strong drink.", "anderson": "", "haweis": "", "noyes": "Be in amazement and be amazed! Be blinded and be blind! They are drunk, but not with wine; They stagger, but not with strong drink!", "webster": "Stay yourselves, and wonder; cry ye out, and cry: they are drunken, but not with wine; they stagger, but not with strong drink.", "vulgate": "obstupescite et admiramini fluctuate et vacillate inebriamini et non a vino movemini et non ebrietate;", "brenton": "Faint ye, and be amazed, and be overpowered, not with strong drink nor with wine."}}, {"v": 10, "ref": "29:10", "o": "כִּֽי נָסַ֨ךְ עֲלֵי/כֶ֤ם יְהוָה֙ ר֣וּחַ תַּרְדֵּמָ֔ה וַ/יְעַצֵּ֖ם אֶת עֵֽינֵי/כֶ֑ם אֶת הַ/נְּבִיאִ֛ים וְ/אֶת רָאשֵׁי/כֶ֥ם הַ/חֹזִ֖ים כִּסָּֽה", "en": {"kjv": "For the Lord hath poured out upon you the spirit of deep sleep, and hath closed your eyes: the prophets and your rulers, the seers hath he covered.", "web": "For Yahweh has poured out on you a spirit of deep sleep, and has closed your eyes, the prophets; and he has covered your heads, the seers.", "bsb": "For the LORD has poured out on you a spirit of deep sleep. He has shut your eyes, O prophets; He has covered your heads, O seers.", "asv": "For Jehovah hath poured out upon you the spirit of deep sleep, and hath closed your eyes, the prophets; and your heads, the seers, hath he covered.", "ylt": "For poured out on you hath Jehovah a spirit of deep sleep, And He closeth your eyes--the prophets, And your heads--the seers--He covered.", "dra": "For the Lord hath mingled for you the spirit of a deep sleep, he will shut up your eyes, he will cover your prophets and princes, that see visions.", "bbe": "For the Lord has sent on you a spirit of deep sleep; and by him your eyes, the prophets, are shut, and your heads, the seers, are covered.", "geneva": "For the Lord hath couered you with a spirite of slumber, and hath shut vp your eyes: the Prophets, and your chiefe Seers hath he couered.", "wycliffe": "For the Lord hath meddlid to you the spirit of sleep; he schal close youre iyen, and schal hile youre profetis, and princes that sien visiouns.", "rotherham": "For Yahweh, hath poured out upon you, a spirit of deep sleep, Yea hath tightly shut your eyes—the prophets,—And, your heads—the seers, hath he covered,", "darby": "For Jehovah hath poured out upon you a spirit of deep sleep, and hath closed your eyes; the prophets and your chiefs, the seers, hath he covered.", "twenty": "", "jps": "For HaShem hath poured out upon you the spirit of deep sleep, and hath closed your eyes; the prophets, and your heads, the seers, hath He covered.", "acv": "For Jehovah has poured out upon you the spirit of deep sleep, and has closed your eyes. The prophets, and your heads, the seers, he has covered.", "anderson": "", "haweis": "", "noyes": "For Jehovah hath poured upon you a spirit of slumber; He hath closed your eyes, the prophets, And covered your heads, the seers;", "webster": "For the LORD hath poured out upon you the spirit of deep sleep, and hath closed your eyes: the prophets and your rulers, the seers hath he covered.", "vulgate": "quoniam miscuit vobis Dominus spiritum soporis claudet oculos vestros prophetas et principes vestros qui vident visiones operiet;", "brenton": "For the Lord has made you to drink a spirit of deep sleep; and he shall close their eyes, and the eyes of their prophets and of their rulers, who see secret things."}}, {"v": 11, "ref": "29:11", "o": "וַ/תְּהִ֨י לָ/כֶ֜ם חָז֣וּת הַ/כֹּ֗ל כְּ/דִבְרֵי֮ הַ/סֵּ֣פֶר הֶֽ/חָתוּם֒ אֲשֶֽׁר יִתְּנ֣וּ אֹת֗/וֹ אֶל יוֹדֵ֥עַ ה/ספר סֵ֛פֶר לֵ/אמֹ֖ר קְרָ֣א נָא זֶ֑ה וְ/אָמַר֙ לֹ֣א אוּכַ֔ל כִּ֥י חָת֖וּם הֽוּא", "en": {"kjv": "And the vision of all is become unto you as the words of a book that is sealed, which men deliver to one that is learned, saying, Read this, I pray thee: and he saith, I cannot; for it is sealed:", "web": "All vision has become to you like the words of a book that is sealed, which men deliver to one who is educated, saying, “Read this, please”; and he says, “I can’t, for it is sealed:”", "bsb": "And the entire vision will be to you like the words sealed in a scroll. If it is handed to someone to read, he will say, “I cannot, because it is sealed.”", "asv": "And all vision is become unto you as the words of a book that is sealed, which men deliver to one that is learned, saying, Read this, I pray thee; and he saith, I cannot, for it is sealed:", "ylt": "And the vision of the whole is to you, As words of the sealed book, That they give unto one knowing books, Saying, `Read this, we pray thee,' And he hath said, `I am not able, for it is sealed;'", "dra": "And the vision of all shall be unto you as the words of a book that is sealed which when they shall deliver to one that is learned, they shall say: Read this: and he shall answer: I cannot, for it is sealed.", "bbe": "And the vision of all this has become to you like the words of a book which is shut, which men give to one who has knowledge of writing, saying, Make clear to us what is in the book: and he says, I am not able to, for the book is shut:", "geneva": "And the vision of them all is become vnto you, as the wordes of a booke that is sealed vp, which they deliuer to one that can reade, saying, Reade this, I pray thee. Then shall he say, I can not: for it is sealed.", "wycliffe": "And the visioun of alle profetis schal be to you as the wordis of a book aseelid; which whanne thei schulen yyue to hym that kan lettris, thei schulen seie, Rede thou this book; and he schal answere, Y may not, for it is aseelid.", "rotherham": "And so all vision hath become unto you as the words of a writing that is sealed, Which is delivered unto one acquainted with writing, saying, Pray thee read this, And he saith, I cannot, for it is sealed;", "darby": "And the whole vision is become unto you as the words of a book that is sealed, which they give to one that can read, saying, Read this, I pray thee; and he saith, I cannot, for it is sealed.", "twenty": "", "jps": "And the vision of all this is become unto you as the words of a writing that is sealed, which men deliver to one that is learned, saying: 'Read this, I pray thee'; and he saith: 'I cannot, for it is sealed';", "acv": "And all vision has become to you as the words of a book that is sealed, which men deliver to a man who is learned, saying, Read this, I pray thee. And he says, I cannot, for it is sealed.", "anderson": "", "haweis": "", "noyes": "And so every vision is to you as the words of a sealed book, Which is given to a man that is skilled in writing, Saying, \"Read this, I pray thee\"; But he answereth, \"I cannot, for it is sealed.\"", "webster": "And the vision of all is become to you as the words of a book that is sealed, which [men] deliver to one that is learned, saying, Read this, I pray thee: and he saith, I cannot; for it [is] sealed:", "vulgate": "et erit vobis visio omnium sicut verba libri signati quem cum dederint scienti litteras dicent lege istum et respondebit non possum signatus est enim;", "brenton": "And all these things shall be to you as the words of this sealed book, which if they shall give to a learned man, saying, Read this, he shall then say, I cannot read it, for it is sealed."}}, {"v": 12, "ref": "29:12", "o": "וְ/נִתַּ֣ן הַ/סֵּ֗פֶר עַל֩ אֲשֶׁ֨ר לֹֽא יָדַ֥ע סֵ֛פֶר לֵ/אמֹ֖ר קְרָ֣א נָא זֶ֑ה וְ/אָמַ֕ר לֹ֥א יָדַ֖עְתִּי סֵֽפֶר", "en": {"kjv": "And the book is delivered to him that is not learned, saying, Read this, I pray thee: and he saith, I am not learned.", "web": "and the book is delivered to one who is not educated, saying, “Read this, please”; and he says, “I can’t read.”", "bsb": "Or if the scroll is handed to one unable to read, he will say, “I cannot read.”", "asv": "and the book is delivered to him that is not learned, saying, Read this, I pray thee; and he saith, I am not learned.", "ylt": "And the book is given to him who hath not known books, Saying, `Read this, we pray thee,' And he hath said, `I have not known books.'", "dra": "And the book shall be given to one that knoweth no letters, and it shall be said to him: Read: and he shall answer: I know no letters.", "bbe": "And they give it to one without learning, saying, Make clear to us what is in the book: and he says, I have no knowledge of writing.", "geneva": "And the booke is giuen vnto him that can not reade, saying, Reade this, I pray thee. And he shall say, I can not reade.", "wycliffe": "And the book schal be youun to him that kan not lettris, and it schal be seid to hym, Rede thou; and he schal answere, Y kan no lettris.", "rotherham": "And then the writing is delivered to one unacquainted with writing, saying, Pray thee read this, And he saith I am not acquainted with writing.", "darby": "And they give the book to him that cannot read, saying, Read this, I pray thee; and he saith, I cannot read.", "twenty": "", "jps": "and the writing is delivered to him that is not learned, saying: 'Read this, I pray thee'; and he saith: 'I am not learned.'", "acv": "And the book is delivered to him who is not learned, saying, Read this, I pray thee. And he says, I am not learned.", "anderson": "", "haweis": "", "noyes": "Or, if he give it to one that is not skilled in writing, Saying, \"Read this, I pray thee,\" He answereth, \"I am not skilled in writing.\"", "webster": "And the book is delivered to him that is not learned, saying, Read this, I pray thee: and he saith, I am not learned.", "vulgate": "et dabitur liber nescienti litteras diceturque ei lege et respondebit nescio litteras;", "brenton": "And this book shall be given into the hands of a man that is unlearned, and one shall say to him, Read this; and he shall say, I am not learned."}}, {"v": 13, "ref": "29:13", "o": "וַ/יֹּ֣אמֶר אֲדֹנָ֗/י יַ֚עַן כִּ֤י נִגַּשׁ֙ הָ/עָ֣ם הַ/זֶּ֔ה בְּ/פִ֤י/ו וּ/בִ/שְׂפָתָי/ו֙ כִּבְּד֔וּ/נִי וְ/לִבּ֖/וֹ רִחַ֣ק מִמֶּ֑/נִּי וַ/תְּהִ֤י יִרְאָתָ/ם֙ אֹתִ֔/י מִצְוַ֥ת אֲנָשִׁ֖ים מְלֻמָּדָֽה", "en": {"kjv": "Wherefore the Lord said, Forasmuch as this people draw near me with their mouth, and with their lips do honour me, but have removed their heart far from me, and their fear toward me is taught by the precept of men:", "web": "The Lord said, “Because this people draws near with their mouth and with their lips to honor me, but they have removed their heart far from me, and their fear of me is a commandment of men which has been taught;", "bsb": "Therefore the Lord said: “These people draw near to Me with their mouths and honor Me with their lips, but their hearts are far from Me. Their worship of Me is but rules taught by men.", "asv": "And the Lord said, Forasmuch as this people draw nigh unto me, and with their mouth and with their lips do honor me, but have removed their heart far from me, and their fear of me is a commandment of men which hath been taught them;", "ylt": "And the Lord saith: Because drawn near hath this people, with its mouth, And with its lips they have honoured Me, And its heart it hath put far off from Me, And their fear of Me is--A precept of men is taught!", "dra": "And the Lord said: Forasmuch as this people draw near me with their mouth, and with their lips glorify me, but their heart is far from me, and they have feared me with the commandment and doctrines of men:", "bbe": "And the Lord said, because this people come near to me with their mouths, and give honour to me with their lips, but their heart is far from me, and their fear of me is false, a rule given them by the teaching of men;", "geneva": "Therefore the Lord sayd, Because this people come neere vnto me with their mouth, and honour me with their lips, but haue remooued their heart farre from me, and their feare toward me was taught by the precept of men,", "wycliffe": "And the Lord seide, For that this puple neiyeth with her mouth, and glorifieth me with her lippis, but her herte is fer fro me; and thei dredden me for the comaundement and techyngis of men, therfor lo!", "rotherham": "Wherefore My Lord hath said,—Because this people, hath drawn near with their mouth, And with their lips, have honoured me, But their heart, have they moved far from me, And so their reverence of me hath become A commandment of men in which they have been schooled,", "darby": "And the Lord saith, Forasmuch as this people draw near with their mouth, and honour me with their lips, but their heart is removed far from me, and their fear of me is a commandment taught of men;", "twenty": "", "jps": "And the L-rd said: Forasmuch as this people draw near, and with their mouth and with their lips do honour Me, but have removed their heart far from Me, and their fear of Me is a commandment of men learned by rote;", "acv": "And the Lord said, Inasmuch as this people draw near me with their mouth, and honor me with their lips, but have removed their heart far from me, but in vain they worship me, teaching the commandments and doctrines of men.", "anderson": "", "haweis": "", "noyes": "Therefore saith the Lord, Since this people draweth near to me with their mouth, And honoreth me with their lips, While their heart is far from me, And their worship of me is according to the commandments of men,", "webster": "Wherefore the Lord said, Forasmuch as this people draw near [me] with their mouth, and with their lips do honor me, but have removed their heart far from me, and their fear towards me is taught by the precept of men:", "vulgate": "et dixit Dominus eo quod adpropinquat populus iste ore suo et labiis suis glorificat me cor autem eius longe est a me et timuerunt me mandato hominum et doctrinis;", "brenton": "And the Lord has said, This people draw nigh to me with their mouth, and they honour me with their lips, but their heart is far from me: but in vain do they worship me, teaching the commandments and doctrines of men."}}, {"v": 14, "ref": "29:14", "o": "לָ/כֵ֗ן הִנְ/נִ֥י יוֹסִ֛ף לְ/הַפְלִ֥יא אֶת הָֽ/עָם הַ/זֶּ֖ה הַפְלֵ֣א וָ/פֶ֑לֶא וְ/אָֽבְדָה֙ חָכְמַ֣ת חֲכָמָ֔י/ו וּ/בִינַ֥ת נְבֹנָ֖י/ו תִּסְתַּתָּֽר", "en": {"kjv": "Therefore, behold, I will proceed to do a marvellous work among this people, even a marvellous work and a wonder: for the wisdom of their wise men shall perish, and the understanding of their prudent men shall be hid.", "web": "therefore, behold, I will proceed to do a marvelous work among this people, even a marvelous work and a wonder; and the wisdom of their wise men will perish, and the understanding of their prudent men will be hidden.”", "bsb": "Therefore I will again confound these people with wonder upon wonder. The wisdom of the wise will vanish, and the intelligence of the intelligent will be hidden.”", "asv": "therefore, behold, I will proceed to do a marvellous work among this people, even a marvellous work and a wonder; and the wisdom of their wise men shall perish, and the understanding of their prudent men shall be hid.", "ylt": "Therefore, lo, I am adding to do wonderfully with this people, A wonder, and a marvel, And perished hath the wisdom of its wise ones, And the understanding of its intelligent ones hideth itself.'", "dra": "Therefore behold I will proceed to cause an admiration in this people, by a great and wonderful miracle: for wisdom shall perish from their wise men, and the understanding of their prudent men shall be hid.", "bbe": "For this cause I will again do a strange thing among this people, a thing to be wondered at: and the wisdom of their wise men will come to nothing, and the sense of their guides will no longer be seen.", "geneva": "Therefore behold, I wil againe doe a marueilous worke in this people, euen a marueilous worke, and a wonder: for the wisdome of their wise men shall perish, and the vnderstanding of their prudent men shalbe hid.", "wycliffe": "Y schal adde, that Y make wondryng to this puple, in a greet myracle and wondurful; for whi wisdom schal perische fro wise men therof, and the vndurstondyng of prudent men therof schal be hid.", "rotherham": "Therefore, behold me! again dealing wonderfully with this people, doing wonderfully a wonderful thing,—So shall perish, the wisdom of their wise men, And the intelligence of their intelligent men, shall vanish!", "darby": "therefore, behold, I will proceed to do marvellously with this people, to do marvellously, even with wonder, and the wisdom of their wise [men] shall perish, and the understanding of their intelligent ones shall be hid.", "twenty": "", "jps": "Therefore, behold, I will again do a marvellous work among this people, even a marvellous work and a wonder; and the wisdom of their wise men shall perish, and the prudence of their prudent men shall be hid.", "acv": "Therefore, behold, I will proceed to do a marvelous work among this people, even a marvelous work and a wonder. I will destroy the wisdom of the wise, and the understanding of their prudent men shall be hidden.", "anderson": "", "haweis": "", "noyes": "Therefore, behold, I will proceed to deal marvellously with this people; Marvellously and wonderfully, For the wisdom of their wise men shall perish, And the prudence of the prudent shall be hid.", "webster": "Therefore behold, I will proceed to do a marvelous work among this people, [even] an astonishing work and a wonder: for the wisdom of their wise [men] shall perish, and the understanding of their prudent [men] shall be hid.", "vulgate": "ideo ecce ego addam ut admirationem faciam populo huic miraculo grandi et stupendo peribit enim sapientia a sapientibus eius et intellectus prudentium eius abscondetur;", "brenton": "Therefore behold I will proceed to remove this people, and I will remove them: and I will destroy the wisdom of the wise, and will hide the understanding of the prudent."}}, {"v": 15, "ref": "29:15", "o": "ה֛וֹי הַ/מַּעֲמִיקִ֥ים מֵֽ/יהוָ֖ה לַ/סְתִּ֣ר עֵצָ֑ה וְ/הָיָ֤ה בְ/מַחְשָׁךְ֙ מַֽעֲשֵׂי/הֶ֔ם וַ/יֹּ֣אמְר֔וּ מִ֥י רֹאֵ֖/נוּ וּ/מִ֥י יוֹדְעֵֽ/נוּ", "en": {"kjv": "Woe unto them that seek deep to hide their counsel from the Lord, and their works are in the dark, and they say, Who seeth us? and who knoweth us?", "web": "Woe to those who deeply hide their counsel from Yahweh, and whose works are in the dark, and who say, “Who sees us?” and “Who knows us?”", "bsb": "Woe to those who dig deep to hide their plans from the LORD. In darkness they do their works and say, “Who sees us, and who will know?”", "asv": "Woe unto them that hide deep their counsel from Jehovah, and whose works are in the dark, and that say, Who seeth us? and who knoweth us?", "ylt": "Woe to those going deep from Jehovah to hide counsel, And whose works have been in darkness. And they say, `Who is seeing us? And who is knowing us?'", "dra": "Woe to you that are deep of heart, to hide your counsel from the Lord: and their works are in the dark, and they say: Who seeth us, and who knoweth us?", "bbe": "Cursed are those who go deep to keep their designs secret from the Lord, and whose works are in the dark, and who say, Who sees us? and who has knowledge of our acts?", "geneva": "Wo vnto them that seeke deepe to hide their counsell from the Lord: for their workes are in darkenes, and they say, Who seeth vs? and who knoweth vs?", "wycliffe": "Wo to you that ben hiye of herte, that ye hide counsel fro the Lord; the werkis of whiche ben in derknessis, and thei seien, Who seeth vs, and who knowith vs?", "rotherham": "Alas! for them who would fain have been too deep for Yahweh by giving secret counsel,—and therefore in the dark, have been their doings, and they have said Who can see us? and—Who can understand us?", "darby": "Woe unto them that hide deep, far from Jehovah, their counsel! And their works are in the dark, and they say, Who seeth us? and who knoweth us?", "twenty": "", "jps": "Woe unto them that seek deep to hide their counsel from HaShem, and their works are in the dark, and they say: 'Who seeth us? and who knoweth us?'", "acv": "Woe to those who hide deep their counsel from Jehovah, and whose works are in the dark, and who say, Who sees us? and, Who knows us?", "anderson": "", "haweis": "", "noyes": "Woe to them that hide deep their purposes from Jehovah, Whose work is in darkness; That say, Who seeth us? Who knoweth us?", "webster": "Woe to them that seek deep to hide their counsel from the LORD, and their works are in the dark, and they say, Who seeth us? and who knoweth us?", "vulgate": "vae qui profundi estis corde ut a Domino abscondatis consilium quorum sunt in tenebris opera et dicunt quis videt nos et quis novit nos;", "brenton": "Woe to them that deepen their counsel, and not by the Lord. Woe to them that take secret counsel, and whose works are in darkness, and they say, Who has seen us? and who shall know us, or what we do?"}}, {"v": 16, "ref": "29:16", "o": "הַ֨פְכְּ/כֶ֔ם אִם כְּ/חֹ֥מֶר הַ/יֹּצֵ֖ר יֵֽחָשֵׁ֑ב כִּֽי יֹאמַ֨ר מַעֲשֶׂ֤ה לְ/עֹשֵׂ֨/הוּ֙ לֹ֣א עָשָׂ֔/נִי וְ/יֵ֛צֶר אָמַ֥ר לְ/יוֹצְר֖/וֹ לֹ֥א הֵבִֽין", "en": {"kjv": "Surely your turning of things upside down shall be esteemed as the potter’s clay: for shall the work say of him that made it, He made me not? or shall the thing framed say of him that framed it, He had no understanding?", "web": "You turn things upside down! Should the potter be thought to be like clay; that the thing made should say about him who made it, “He didn’t make me”; or the thing formed say of him who formed it, “He has no understanding?”", "bsb": "You have turned things upside down, as if the potter were regarded as clay. Shall what is formed say to him who formed it, “He did not make me”? Can the pottery say of the potter, “He has no understanding”?", "asv": "Ye turn things upside down! Shall the potter be esteemed as clay; that the thing made should say of him that made it, He made me not; or the thing formed say of him that formed it, He hath no understanding?", "ylt": "Your perversion! as clay is the potter esteemed? That the work saith of its maker, `He hath not made me?' And the framed thing said of its framer, `He did not understand?'", "dra": "This thought of yours is perverse: as if the clay should think against the potter, and the work should say to the maker thereof: Thou madest me not: or the thing framed should say to him that fashioned it: Thou understandest not.", "bbe": "You are turning things upside down! Is the wet earth the same to you as the one who is forming it? will the thing made say of him who made it, He made me not: or the thing formed say of him who gave it form, He has no knowledge?", "geneva": "Your turning of deuises shall it not be esteemed as the potters clay? for shall the worke say of him that made it, Hee made me not? or the thing formed, say of him that facioned it, He had none vnderstanding?", "wycliffe": "This thouyt of you is weiward, as if cley thenke ayens a pottere, and the werk seie to his makere, Thou madist not me; and a thing `that is maad, seie to his makere, Thou vndurstondist not.", "rotherham": "Your perverseness! As if like clay, the potter could be reckoned; For shall, the thing made say of him that made it, he made me not? Or hath the thing fashioned ever said of him that fashioned it, He hath no understanding.", "darby": "[Oh] your perverseness! — Shall the potter be esteemed as the clay, so that the work should say of him that made it, He made me not; or the thing formed say of him that formed it, He hath no understanding?", "twenty": "", "jps": "O your perversity! Shall the potter be esteemed as clay; that the thing made should say of him that made it: 'He made me not'; or the thing framed say of him that framed it: 'He hath no understanding?'", "acv": "Ye turn things upside down! Shall the potter be esteemed as clay, that the thing made should say of him who made it, He did not make me, or the thing formed say of him who formed it, He has no understanding?", "anderson": "", "haweis": "", "noyes": "Alas, your perverseness! Is the potter to be esteemed as the clay, That the work should say of its maker, He made me not? And the thing formed say of him that formed it, He hath no understanding?", "webster": "Surely your turning of things upside down shall be esteemed as the potter's clay: for shall the work say of him that made it, He made me not? or shall the thing framed say of him that framed it, He had no understanding?", "vulgate": "perversa est haec vestra cogitatio quasi lutum contra figulum cogitet et dicat opus factori suo non fecisti me et figmentum dicat fictori suo non intellegis;", "brenton": "Shall ye not be counted as clay of the potter? Shall the thing formed say to him that formed it, Thou didst not form me? or the work to the maker, Thou hast not made me wisely?"}}, {"v": 17, "ref": "29:17", "o": "הֲ/לוֹא עוֹד֙ מְעַ֣ט מִזְעָ֔ר וְ/שָׁ֥ב לְבָנ֖וֹן לַ/כַּרְמֶ֑ל וְ/הַ/כַּרְמֶ֖ל לַ/יַּ֥עַר יֵחָשֵֽׁב", "en": {"kjv": "Is it not yet a very little while, and Lebanon shall be turned into a fruitful field, and the fruitful field shall be esteemed as a forest?", "web": "Isn’t it yet a very little while, and Lebanon will be turned into a fruitful field, and the fruitful field will be regarded as a forest?", "bsb": "In a very short time, will not Lebanon become an orchard, and the orchard seem like a forest?", "asv": "Is it not yet a very little while, and Lebanon shall be turned into a fruitful field, and the fruitful field shall be esteemed as a forest?", "ylt": "Is it not yet a very little, And turned hath Lebanon to a fruitful field, And the fruitful field for a forest is reckoned?", "dra": "Is it not yet a very little while, and Libanus shall be turned into charmel, and charmel shall be esteemed as a forest?", "bbe": "In a very short time Lebanon will become a fertile field, and the fertile field will seem like a wood.", "geneva": "Is it not yet but a litle while, and Lebanon shall be turned into Carmel? and Carmel shall be counted as a forest?", "wycliffe": "Whether not yit in a litil time and schort the Liban schal be turned in to Chermel, and Chermel schal be arettid in to the forest?", "rotherham": "Is it not yet a very little while, And Lebanon shall be turned, into garden land,—And garden land, for a forest, be reckoned?", "darby": "Is it not yet a very little while, and Lebanon shall be turned into a fruitful field, and the fruitful field shall be esteemed as a forest?", "twenty": "", "jps": "Is it not yet a very little while, and Lebanon shall be turned into a fruitful field, and the fruitful field shall be esteemed as a forest?", "acv": "Is it not yet a very little while, and Lebanon shall be turned into a fruitful field, and the fruitful field shall be esteemed as a forest?", "anderson": "", "haweis": "", "noyes": "Is it not yet a very little while, And Lebanon shall be changed to a fruitful field, And the fruitful field be esteemed a forest.", "webster": "[Is] it not yet a very little while, and Lebanon shall be turned into a fruitful field, and the fruitful field shall be esteemed as a forest?", "vulgate": "nonne adhuc in modico et in brevi convertetur Libanus in Chermel et Chermel in saltum reputabitur;", "brenton": "Is it not yet a little while, and Libanus shall be changed as the mountains of Chermel, and Chermel shall be reckoned as a forest?"}}, {"v": 18, "ref": "29:18", "o": "וְ/שָׁמְע֧וּ בַ/יּוֹם הַ/ה֛וּא הַ/חֵרְשִׁ֖ים דִּבְרֵי סֵ֑פֶר וּ/מֵ/אֹ֣פֶל וּ/מֵ/חֹ֔שֶׁךְ עֵינֵ֥י עִוְרִ֖ים תִּרְאֶֽינָה", "en": {"kjv": "And in that day shall the deaf hear the words of the book, and the eyes of the blind shall see out of obscurity, and out of darkness.", "web": "In that day, the deaf will hear the words of the book, and the eyes of the blind will see out of obscurity and out of darkness.", "bsb": "On that day the deaf will hear the words of the scroll, and out of the deep darkness the eyes of the blind will see.", "asv": "And in that day shall the deaf hear the words of the book, and the eyes of the blind shall see out of obscurity and out of darkness.", "ylt": "And heard in that day have the deaf the words of a book, And out of thick darkness, and out of darkness, The eyes of the blind do see.", "dra": "And in that day the deaf shall hear the words of the book, and out of darkness and obscurity the eyes of the blind shall see.", "bbe": "And in that day those whose ears are stopped will be hearing the words of the book; and the eyes of the blind will see through the mist and the dark.", "geneva": "And in that day shall the deafe heare the wordes of the booke, and the eyes of the blinde shall see out of obscuritie, and out of darkenesse.", "wycliffe": "And in that dai deef men schulen here the wordis of the book, and the iyen of blynde men schulen se fro derknessis and myisty;", "rotherham": "Therefore, in that day, shall the deaf hear the words of a book,—And out of gloom and darkness, the eyes of the blind shall see;", "darby": "And in that day shall the deaf hear the words of the book, and, out of obscurity and out of darkness, the eyes of the blind shall see;", "twenty": "", "jps": "And in that day shall the deaf hear the words of a book, and the eyes of the blind shall see out of obscurity and out of darkness.", "acv": "And in that day the deaf shall hear the words of the book, and the eyes of the blind shall see out of obscurity and out of darkness.", "anderson": "", "haweis": "", "noyes": "And in that day shall the deaf hear the words of the book, And out of mist and darkness shall the eyes of the blind see.", "webster": "And in that day shall the deaf hear the words of the book, and the eyes of the blind shall see out of obscurity, and out of darkness.", "vulgate": "et audient in die illa surdi verba libri et de tenebris et caligine oculi caecorum videbunt;", "brenton": "And in that day the deaf shall hear the words of the book, and they that are in darkness, and they that are in mist: the eyes of the blind shall see,"}}, {"v": 19, "ref": "29:19", "o": "וְ/יָסְפ֧וּ עֲנָוִ֛ים בַּֽ/יהוָ֖ה שִׂמְחָ֑ה וְ/אֶבְיוֹנֵ֣י אָדָ֔ם בִּ/קְד֥וֹשׁ יִשְׂרָאֵ֖ל יָגִֽילוּ", "en": {"kjv": "The meek also shall increase their joy in the Lord, and the poor among men shall rejoice in the Holy One of Israel.", "web": "The humble also will increase their joy in Yahweh, and the poor among men will rejoice in the Holy One of Israel.", "bsb": "The humble will increase their joy in the LORD, and the poor among men will rejoice in the Holy One of Israel.", "asv": "The meek also shall increase their joy in Jehovah, and the poor among men shall rejoice in the Holy One of Israel.", "ylt": "And the humble have added joy in Jehovah, And the poor among men In the Holy One of Israel rejoice.", "dra": "And the meek shall increase their joy in the Lord, and the poor men shall rejoice in the Holy One of Israel.", "bbe": "And the poor will have their joy in the Lord increased, and those in need will be glad in the Holy One of Israel.", "geneva": "The meeke in the Lord shall receiue ioye againe, and the poore men shall reioyce in the holy one of Israel.", "wycliffe": "and mylde men schulen encreesse gladnesse in the Lord, and pore men schulen make ful out ioie in the hooli of Israel.", "rotherham": "And again shall the humbled in Yahweh, have joy,—And the needy of mankind in the Holy One of Israel, exult;", "darby": "and the meek shall increase their joy in Jehovah, and the needy among men shall rejoice in the Holy One of Israel.", "twenty": "", "jps": "The humble also shall increase their joy in HaShem, and the neediest among men shall exult in the Holy One of Israel.", "acv": "The meek also shall increase their joy in Jehovah, and the poor among men shall rejoice in the Holy One of Israel.", "anderson": "", "haweis": "", "noyes": "The afflicted shall exceedingly rejoice in Jehovah, And the poor shall exult in the Holy One of Israel.", "webster": "The meek also shall increase [their] joy in the LORD, and the poor among men shall rejoice in the Holy One of Israel.", "vulgate": "et addent mites in Domino laetitiam et pauperes homines in Sancto Israhel exultabunt;", "brenton": "and the poor shall rejoice with joy because of the Lord, and they that had no hope among men shall be filled with joy."}}, {"v": 20, "ref": "29:20", "o": "כִּֽי אָפֵ֥ס עָרִ֖יץ וְ/כָ֣לָה לֵ֑ץ וְ/נִכְרְת֖וּ כָּל שֹׁ֥קְדֵי אָֽוֶן", "en": {"kjv": "For the terrible one is brought to nought, and the scorner is consumed, and all that watch for iniquity are cut off:", "web": "For the ruthless is brought to nothing, and the scoffer ceases, and all those who are alert to do evil are cut off—", "bsb": "For the ruthless will vanish, the mockers will disappear, and all who look for evil will be cut down—", "asv": "For the terrible one is brought to nought, and the scoffer ceaseth, and all they that watch for iniquity are cut off;", "ylt": "For ceased hath the terrible one, And consumed hath been the scorner, And cut off have been all watching for iniquity,", "dra": "For he that did prevail hath failed, the scorner is consumed, and they are all cut off that watched for iniquity:", "bbe": "For the cruel one has come to nothing; and those who make sport of the Lord are gone; and those who are watching to do evil are cut off:", "geneva": "For the cruel man shall cease, and the scornefull shalbe consumed: and all that hasted to iniquitie, shalbe cut off:", "wycliffe": "For he that hadde the maistrie, failide, and the scornere is endid, and alle thei ben kit doun that walkiden on wickidnesse;", "rotherham": "For the tyrant, hath vanished, And the scoffer, is no more, Yea cut off are all who watch for iniquity:—", "darby": "For the terrible one shall come to nought, and the scorner shall be no more, and all that watch for iniquity shall be cut off,", "twenty": "", "jps": "For the terrible one is brought to nought, and the scorner ceaseth, and all they that watch for iniquity are cut off;", "acv": "For the terrible one is brought to nothing, and the scoffer ceases. And all those who watch for iniquity are cut off,", "anderson": "", "haweis": "", "noyes": "For the oppressor hath come to naught; the scoffer is destroyed; And all that watched for iniquity are cut off;", "webster": "For the terrible one is brought to naught, and the scoffer is consumed, and all that watch for iniquity are cut off:", "vulgate": "quoniam defecit qui praevalebat consummatus est inlusor et succisi sunt omnes qui vigilabant super iniquitatem;", "brenton": "The lawless man has come to nought, and the proud man has perished, and they that transgress mischievously have been utterly destroyed:"}}, {"v": 21, "ref": "29:21", "o": "מַחֲטִיאֵ֤י אָדָם֙ בְּ/דָבָ֔ר וְ/לַ/מּוֹכִ֥יחַ בַּ/שַּׁ֖עַר יְקֹשׁ֑וּ/ן וַ/יַּטּ֥וּ בַ/תֹּ֖הוּ צַדִּֽיק", "en": {"kjv": "That make a man an offender for a word, and lay a snare for him that reproveth in the gate, and turn aside the just for a thing of nought.", "web": "who cause a person to be indicted by a word, and lay a snare for the arbiter in the gate, and who deprive the innocent of justice with false testimony.", "bsb": "those who indict a man with a word, who ensnare the mediator at the gate, and who with false charges deprive the innocent of justice.", "asv": "that make a man an offender in his cause, and lay a snare for him that reproveth in the gate, and turn aside the just with a thing of nought.", "ylt": "Causing men to sin in word, And for a reprover in the gate lay a snare, And turn aside into emptiness the righteous.", "dra": "That made men sin by word, and supplanted him that reproved them in the gate, and declined in vain from the just.", "bbe": "Who give help to a man in a wrong cause, and who put a net for the feet of him who gives decisions in the public place, taking away a man's right without cause.", "geneva": "Which made a man to sinne in ye worde, and tooke him in a snare: which reproued them in the gate, and made the iust to fall without cause.", "wycliffe": "whiche maden men to do synne in word, and disseyueden a repreuere in the yate, and bowiden awey in veyn fro a iust man.", "rotherham": "Who bring a man into condemnation with a rumour, And for him that decideth in the gate, lay a snare,—And have driven away, for a thing of nought, one who was righteous.", "darby": "that make a man an offender for a word, and lay a snare for him that reproveth in the gate, and pervert [the judgment of] the righteous by futility.", "twenty": "", "jps": "That make a man an offender by words, and lay a snare for him that reproveth in the gate, and turn aside the just with a thing of nought.", "acv": "who make a man an offender in his cause, and lay a snare for him who reproves in the gate, and turn aside the just with a thing of nothing.", "anderson": "", "haweis": "", "noyes": "Who condemned a man in his cause, And laid snares for him who defended himself in the gate, And with falsehood caused the righteous to fail.", "webster": "That make a man an offender for a word, and lay a snare for him that reproveth in the gate, and turn aside the just for a thing of naught.", "vulgate": "qui peccare faciebant homines in verbo et arguentem in porta subplantabant et declinaverunt frustra a iusto;", "brenton": "and they that cause men to sin by a word: and men shall make all that reprove in the gates an offence, because they have unjustly turned aside the righteous."}}, {"v": 22, "ref": "29:22", "o": "לָ/כֵ֗ן כֹּֽה אָמַ֤ר יְהוָה֙ אֶל בֵּ֣ית יַֽעֲקֹ֔ב אֲשֶׁ֥ר פָּדָ֖ה אֶת אַבְרָהָ֑ם לֹֽא עַתָּ֤ה יֵבוֹשׁ֙ יַֽעֲקֹ֔ב וְ/לֹ֥א עַתָּ֖ה פָּנָ֥י/ו יֶחֱוָֽרוּ", "en": {"kjv": "Therefore thus saith the Lord, who redeemed Abraham, concerning the house of Jacob, Jacob shall not now be ashamed, neither shall his face now wax pale.", "web": "Therefore thus says Yahweh, who redeemed Abraham, concerning the house of Jacob: “Jacob shall no longer be ashamed, neither shall his face grow pale.", "bsb": "Therefore the LORD who redeemed Abraham says of the house of Jacob: “No longer will Jacob be ashamed and no more will his face grow pale.", "asv": "Therefore thus saith Jehovah, who redeemed Abraham, concerning the house of Jacob: Jacob shall not now be ashamed, neither shall his face now wax pale.", "ylt": "Therefore, thus said Jehovah, Who ransomed Abraham, Concerning the house of Jacob: `Not now ashamed is Jacob, Nor now doth his face become pale,", "dra": "Therefore thus saith the Lord to the house of Jacob, he that redeemed Abraham: Jacob shall not now be confounded, neither shall his countenance now be ashamed:", "bbe": "For this reason the Lord, the saviour of Abraham, says about the family of Jacob, Jacob will not now be put to shame, or his face be clouded with fear.", "geneva": "Therefore thus sayth the Lord vnto the house of Iaakob, euen hee that redeemed Abraham, Iaakob shall not now be confounded, neither now shall his face be pale.", "wycliffe": "For this thing the Lord, that ayen bouyte Abraham, seith these thingis to the hous of Jacob, Jacob schal not be confoundid now, nether now his cheer schal be aschamed; but whanne he schal se hise sones,", "rotherham": "Therefore, Thus, saith Yahweh, concerning the house of Jacob, [even he saith it] who redeemed Abraham,—Not now, shall, Jacob turn pale, And, not now, shall their faces whiten;", "darby": "Therefore thus saith Jehovah who redeemed Abraham, concerning the house of Jacob: Jacob shall not now be ashamed, neither shall his face now be pale;", "twenty": "", "jps": "Therefore thus saith HaShem, who redeemed Abraham, concerning the house of Jacob: Jacob shall not now be ashamed, neither shall his face now wax pale;", "acv": "Therefore thus says Jehovah, who redeemed Abraham, concerning the house of Jacob: Jacob shall not now be ashamed, nor shall his face now grow pale.", "anderson": "", "haweis": "", "noyes": "Therefore concerning the house of Jacob thus saith Jehovah, He that redeemed Abraham: No more shall Jacob be ashamed, And no more shall his face grow pale.", "webster": "Therefore thus saith the LORD, who redeemed Abraham, concerning the house of Jacob, Jacob shall not now be ashamed, neither shall his face now become pale.", "vulgate": "propter hoc haec dicit Dominus ad domum Iacob qui redemit Abraham non modo confundetur Iacob nec modo vultus eius erubescet;", "brenton": "Therefore thus saith the Lord concerning the house of Jacob, whom he set apart from Abraam, Jacob shall not now be ashamed, neither shall he now change countenance."}}, {"v": 23, "ref": "29:23", "o": "כִּ֣י בִ֠/רְאֹת/וֹ יְלָדָ֞י/ו מַעֲשֵׂ֥ה יָדַ֛/י בְּ/קִרְבּ֖/וֹ יַקְדִּ֣ישֽׁוּ שְׁמִ֑/י וְ/הִקְדִּ֨ישׁוּ֙ אֶת קְד֣וֹשׁ יַֽעֲקֹ֔ב וְ/אֶת אֱלֹהֵ֥י יִשְׂרָאֵ֖ל יַעֲרִֽיצוּ", "en": {"kjv": "But when he seeth his children, the work of mine hands, in the midst of him, they shall sanctify my name, and sanctify the Holy One of Jacob, and shall fear the God of Israel.", "web": "But when he sees his children, the work of my hands, in the midst of him, they will sanctify my name. Yes, they will sanctify the Holy One of Jacob, and will stand in awe of the God of Israel.", "bsb": "For when he sees his children around him, the work of My hands, they will honor My name, they will sanctify the Holy One of Jacob, and they will stand in awe of the God of Israel.", "asv": "But when he seeth his children, the work of my hands, in the midst of him, they shall sanctify my name; yea, they shall sanctify the Holy One of Jacob, and shall stand in awe of the God of Israel.", "ylt": "For in his seeing his children, The work of My hand, in his midst, They sanctify My name, And have sanctified the Holy One of Jacob, And the God of Israel they declare fearful.", "dra": "But when he shall see his children, the work of my hands in the midst of him sanctifying my name, and they shall sanctify the Holy One of Jacob, and shall glorify the God of Israel:", "bbe": "But when they, the children of Jacob, see the work of my hands among them, they will give honour to my name; yes, they will give honour to the Holy One of Jacob, and go in fear of the God of Israel.", "geneva": "But when he seeth his children, the worke of mine hands, in the mids of him, they shall sanctifie my Name, and sanctifie the holy one of Iaakob, and shall feare the God of Israel.", "wycliffe": "the werkis of myn hondis, halewynge my name in the myddis of hym. And thei schulen halewe the hooli of Jacob, and thei schulen preche God of Israel;", "rotherham": "For, when he seeth his children the work of my hands, in his midst, They will hallow my Name,—Yea they will hallow the Holy One of Jacob, And the God of Israel, will they regard with awe.", "darby": "for when he seeth his children, the work of my hands, in the midst of him, they shall hallow my name, and hallow the Holy One of Jacob, and shall fear theGod of Israel.", "twenty": "", "jps": "When he seeth his children, the work of My hands, in the midst of him, that they sanctify My name; yea, they shall sanctify the Holy One of Jacob, and shall stand in awe of the G-d of Israel.", "acv": "But when he sees his children, the work of my hands, in the midst of him, they shall sanctify my name. Yea, they shall sanctify the Holy One of Jacob, and shall stand in awe of the God of Israel.", "anderson": "", "haweis": "", "noyes": "For when his children behold the work of my hands in the midst of them, They shall honor my name. They shall honor the Holy One of Jacob, And reverence the God of Israel.", "webster": "But when he seeth his children, the work of my hands, in the midst of him, they shall sanctify my name, and sanctify the Holy One of Jacob, and shall fear the God of Israel.", "vulgate": "sed cum viderit filios suos opera manuum mearum in medio sui sanctificantes nomen meum et sanctificabunt Sanctum Iacob et Deum Israhel praedicabunt;", "brenton": "But when their children shall have seen my works, they shall sanctify my name for my sake, and they sanctify the Holy One of Jacob, and shall fear the God of Israel."}}, {"v": 24, "ref": "29:24", "o": "וְ/יָדְע֥וּ תֹֽעֵי ר֖וּחַ בִּינָ֑ה וְ/רוֹגְנִ֖ים יִלְמְדוּ לֶֽקַח", "en": {"kjv": "They also that erred in spirit shall come to understanding, and they that murmured shall learn doctrine.", "web": "They also who err in spirit will come to understanding, and those who grumble will receive instruction.”", "bsb": "Then the wayward in spirit will come to understanding, and those who grumble will accept instruction.”", "asv": "They also that err in spirit shall come to understanding, and they that murmur shall receive instruction.", "ylt": "And the erring in spirit have known understanding, And murmurers learn doctrine!'", "dra": "And they that erred in spirit, shall know understanding, and they that murmured, shall learn the law.", "bbe": "Those whose hearts were turned away from him will get knowledge, and those who made an outcry against him will give attention to his teaching.", "geneva": "Then they that erred in spirit, shall haue vnderstanding, and they that murmured, shall learne doctrine.", "wycliffe": "and thei that erren in spirit, schulen knowe vndurstondyng, and idil men schulen lerne the lawe.", "rotherham": "Then will they who erred in spirit comprehend, And the murmurers, accept instruction.", "darby": "And they that are of erring spirit shall know understanding, and the disobedient shall learn doctrine.", "twenty": "", "jps": "They also that err in spirit shall come to understanding, and they that murmur shall learn instruction.", "acv": "They also who err in spirit shall come to understanding, and those who murmur shall receive instruction.", "anderson": "", "haweis": "", "noyes": "They that erred in spirit shall come to understanding, And the obstinate shall receive instruction.", "webster": "They also that erred in spirit shall come to understanding, and they that murmured shall learn doctrine.", "vulgate": "et scient errantes spiritu intellectum et mussitatores discent legem;", "brenton": "And they that erred in spirit shall know understanding, and the murmurers shall learn obedience, and the stammering tongues shall learn to speak peace."}}]}, {"c": 30, "verses": [{"v": 1, "ref": "30:1", "o": "ה֣וֹי בָּנִ֤ים סֽוֹרְרִים֙ נְאֻם יְהוָ֔ה לַ/עֲשׂ֤וֹת עֵצָה֙ וְ/לֹ֣א מִ/נִּ֔י וְ/לִ/נְסֹ֥ךְ מַסֵּכָ֖ה וְ/לֹ֣א רוּחִ֑/י לְמַ֛עַן סְפ֥וֹת חַטָּ֖את עַל חַטָּֽאת", "en": {"kjv": "Woe to the rebellious children, saith the Lord, that take counsel, but not of me; and that cover with a covering, but not of my spirit, that they may add sin to sin:", "web": "“Woe to the rebellious children”, says Yahweh, “who take counsel, but not from me; and who make an alliance, but not with my Spirit, that they may add sin to sin,", "bsb": "“Woe to the rebellious children,” declares the LORD, “to those who carry out a plan that is not Mine, who form an alliance, but against My will, heaping up sin upon sin.", "asv": "Woe to the rebellious children, saith Jehovah, that take counsel, but not of me; and that make a league, but not of my Spirit, that they may add sin to sin,", "ylt": "Woe to apostate sons, The affirmation of Jehovah! To do counsel, and not from Me, And to spread out a covering, and not of My spirit, So as to add sin to sin.", "dra": "Woe to you, apostate children, saith the Lord, that you would take counsel, and not of me: and would begin a web, and not by my spirit, that you might add sin upon sin:", "bbe": "Ho! uncontrolled children, says the Lord, who give effect to a purpose which is not mine, and who make an agreement, but not by my spirit, increasing their sin:", "geneva": "Wo to the rebellious children, sayth the Lord, that take counsell, but not of me, and couer with a couering, but not by my spirit, that they may lay sinne vpon sinne:", "wycliffe": "Wo! sones forsakeris, seith the Lord, that ye schulden make a councel, and not of me; and weue a web, and not bi my spirit, that ye schulden encreesse synne on synne.", "rotherham": "Alas! for sons who are rebellious, Declareth Yahweh. Executing a purpose, but not from me, And pouring out a libation but not from my spirit,—That they may add sin to sin:", "darby": "Woe to the rebellious children, saith Jehovah, who take counsel, but not of me, and who make leagues, but not by my Spirit, that they may heap sin upon sin;", "twenty": "", "jps": "Woe to the rebellious children, saith HaShem, that take counsel, but not of Me; and that form projects, but not of My spirit, that they may add sin to sin;", "acv": "Woe to the rebellious sons, says Jehovah, who take counsel, but not of me, and who make a league, but not of my Spirit, that they may add sin to sin,", "anderson": "", "haweis": "", "noyes": "Woe to the rebellious children, saith Jehovah, Who form plans, and not from me, And make covenants without my spirit, That they may add sin to sin!", "webster": "Woe to the rebellious children, saith the LORD, that take counsel, but not from me; and that cover with a covering, but not of my spirit, that they may add sin to sin:", "vulgate": "vae filii desertores dicit Dominus ut faceretis consilium et non ex me et ordiremini telam et non per spiritum meum ut adderetur peccatum super peccatum;", "brenton": "Woe to the apostate children, saith the Lord: ye have framed counsel, not by me, and covenants not by my Spirit, to add sins to sins:"}}, {"v": 2, "ref": "30:2", "o": "הַ/הֹלְכִים֙ לָ/רֶ֣דֶת מִצְרַ֔יִם וּ/פִ֖/י לֹ֣א שָׁאָ֑לוּ לָ/עוֹז֙ בְּ/מָע֣וֹז פַּרְעֹ֔ה וְ/לַ/חְס֖וֹת בְּ/צֵ֥ל מִצְרָֽיִם", "en": {"kjv": "That walk to go down into Egypt, and have not asked at my mouth; to strengthen themselves in the strength of Pharaoh, and to trust in the shadow of Egypt!", "web": "who set out to go down into Egypt, and have not asked my advice; to strengthen themselves in the strength of Pharaoh, and to take refuge in the shadow of Egypt!", "bsb": "They set out to go down to Egypt without asking My advice, to seek shelter under Pharaoh’s protection and take refuge in Egypt’s shade.", "asv": "that set out to go down into Egypt, and have not asked at my mouth; to strengthen themselves in the strength of Pharaoh, and to take refuge in the shadow of Egypt!", "ylt": "Who are walking to go down to Egypt, And My mouth have not asked, To be strong in the strength of Pharaoh, And to trust in the shadow of Egypt.", "dra": "Who walk to go down into Egypt, and have not asked at my mouth, hoping for help in the strength of Pharao, and trusting in the shadow of Egypt.", "bbe": "Who make a move to go down into Egypt, without authority from me; who are looking to the strength of Pharaoh for help, and whose hope is in the shade of Egypt.", "geneva": "Which walke forth to goe downe into Egypt (and haue not asked at my mouth) to strengthen them selues with the strength of Pharaoh, and trust in the shadowe of Egypt.", "wycliffe": "Whiche goen, to go doun in to Egipt, and ye axiden not my mouth; ye hopynge help in the strengthe of Farao, and ye hauynge trist in the schadewe of Egipt.", "rotherham": "Who are setting out to go down to Egypt, But at my mouth, have not asked,—Betaking them to the protection of Pharaoh And seeking refuge under the shadow of Egypt.", "darby": "who walk to go down into Egypt, and have not asked of my mouth, — to take refuge under the protection of Pharaoh, and trust in the shadow of Egypt!", "twenty": "", "jps": "That walk to go down into Egypt, and have not asked at My mouth; to take refuge in the stronghold of Pharaoh, and to take shelter in the shadow of Egypt!", "acv": "who set out to go down into Egypt, and have not asked at my mouth, to strengthen themselves in the strength of Pharaoh, and to take refuge in the shadow of Egypt!", "anderson": "", "haweis": "", "noyes": "Who go down into Egypt, Without inquiring at my mouth, To seek refuge in Pharaoh’s protection, And to trust in the shadow of Egypt!", "webster": "That walk to go down into Egypt, and have not asked at my mouth; to strengthen themselves in the strength of Pharaoh, and to trust in the shade of Egypt!", "vulgate": "qui ambulatis ut descendatis in Aegyptum et os meum non interrogastis sperantes auxilium in fortitudine Pharao et habentes fiduciam in umbra Aegypti;", "brenton": "even they that proceed to go down into Egypt, but they have not enquired of me, that they might be helped by Pharao, and protected by the Egyptians."}}, {"v": 3, "ref": "30:3", "o": "וְ/הָיָ֥ה לָ/כֶ֛ם מָע֥וֹז פַּרְעֹ֖ה לְ/בֹ֑שֶׁת וְ/הֶ/חָס֥וּת בְּ/צֵל מִצְרַ֖יִם לִ/כְלִמָּֽה", "en": {"kjv": "Therefore shall the strength of Pharaoh be your shame, and the trust in the shadow of Egypt your confusion.", "web": "Therefore the strength of Pharaoh will be your shame, and the refuge in the shadow of Egypt your confusion.", "bsb": "But Pharaoh’s protection will become your shame, and the refuge of Egypt’s shade your disgrace.", "asv": "Therefore shall the strength of Pharaoh be your shame, and the refuge in the shadow of Egypt your confusion.", "ylt": "And the strength of Pharaoh Hath been to you for shame, And the trust in the shadow of Egypt confusion,", "dra": "And the strength of Pharao shall be to your confusion, and the confidence of the shadow of Egypt to your shame.", "bbe": "And the strength of Pharaoh will be your shame, and your hope in the shade of Egypt will come to nothing.", "geneva": "But the strength of Pharaoh shalbe your shame, and the trust in the shadow of Egypt your confusion.", "wycliffe": "And the strengthe of Farao schal be to you in to confusioun, and the trist of the schadewe of Egipt in to schenschipe.", "rotherham": "Therefore shall the protection of Pharaoh become to you a shame, And, the refuge in the shadow of Egypt, an insult;", "darby": "For to you the protection of Pharaoh shall be a shame, and the trust in the shadow of Egypt a confusion.", "twenty": "", "jps": "Therefore shall the stronghold of Pharaoh turn to your shame, and the shelter in the shadow of Egypt to your confusion.", "acv": "Therefore the strength of Pharaoh shall be your shame, and the refuge in the shadow of Egypt your confusion.", "anderson": "", "haweis": "", "noyes": "The protection of Pharaoh shall be your shame; Your trust in the shadow of Egypt your confusion.", "webster": "Therefore shall the strength of Pharaoh be your shame, and the trust in the shade of Egypt [your] confusion.", "vulgate": "et erit vobis fortitudo Pharaonis in confusionem et fiducia umbrae Aegypti in ignominiam;", "brenton": "For the protection of Pharaoh shall be to you a disgrace, and there shall be a reproach to them that trust in Egypt."}}, {"v": 4, "ref": "30:4", "o": "כִּֽי הָי֥וּ בְ/צֹ֖עַן שָׂרָ֑י/ו וּ/מַלְאָכָ֖י/ו חָנֵ֥ס יַגִּֽיעוּ", "en": {"kjv": "For his princes were at Zoan, and his ambassadors came to Hanes.", "web": "For their princes are at Zoan, and their ambassadors have come to Hanes.", "bsb": "For though their princes are at Zoan and their envoys have arrived in Hanes,", "asv": "For their princes are at Zoan, and their ambassadors are come to Hanes.", "ylt": "For in Zoan were his princes, And his messengers reach Hanes.", "dra": "For thy princes were in Tanis, and thy messengers came even to Hanes.", "bbe": "For his chiefs are at Zoan, and his representatives have come to Hanes.", "geneva": "For his princes were at Zoan, and his Ambassadours came vnto Hanes.", "wycliffe": "For whi thi princes weren in Taphnys, and thi messangeris camen til to Anes.", "rotherham": "For their princes have been, in Zoan,—And, their messengers unto Hanes, would draw near.", "darby": "For his princes were at Zoan, and his ambassadors came to Hanes.", "twenty": "", "jps": "For his princes are at Zoan, and his ambassadors are come to Hanes.", "acv": "For their rulers are at Zoan, and their ambassadors have come to Hanes.", "anderson": "", "haweis": "", "noyes": "For their princes are at Zoan, Their ambassadors have arrived at Hanes.", "webster": "For his princes were at Zoan, and his embassadors came to Hanes.", "vulgate": "erant enim in Tanis principes tui et nuntii tui usque ad Anes pervenerunt;", "brenton": "For there are princes in Tanes, evil messengers."}}, {"v": 5, "ref": "30:5", "o": "כֹּ֣ל הבאיש הֹבִ֔ישׁ עַל עַ֖ם לֹא יוֹעִ֣ילוּ לָ֑/מוֹ לֹ֤א לְ/עֵ֨זֶר֙ וְ/לֹ֣א לְ/הוֹעִ֔יל כִּ֥י לְ/בֹ֖שֶׁת וְ/גַם לְ/חֶרְפָּֽה", "en": {"kjv": "They were all ashamed of a people that could not profit them, nor be an help nor profit, but a shame, and also a reproach.", "web": "They shall all be ashamed because of a people that can’t profit them, that are not a help nor profit, but a shame, and also a reproach.”", "bsb": "everyone will be put to shame because of a people useless to them. They cannot be of help; they are good for nothing but shame and reproach.”", "asv": "They shall all be ashamed because of a people that cannot profit them, that are not a help nor profit, but a shame, and also a reproach.", "ylt": "All he made ashamed of a people that profit not, Neither for help, not for profit, But for shame, and also for reproach!", "dra": "They were all confounded at a people that could not profit them: they were no help, nor to any profit, but to confusion and to reproach.", "bbe": "For they have all come with offerings to a people of no use to them, in whom is no help or profit, but only shame and a bad name.", "geneva": "They shalbe all ashamed of the people that cannot profite them, nor helpe nor doe them good, but shalbe a shame and also a reproche.", "wycliffe": "Alle thei weren schent on the puple, that myyten not profite to hem; thei weren not in to help, and in to ony profit, but in to schame and schenschip.", "rotherham": "Every one, hath felt ashamed of a people that could not serve them,—Neither with help, nor with service, But they are a shame, yea even a reproach.", "darby": "They were all ashamed of a people [that] did not profit them, nor were a help or profit, but a shame, and also a reproach.", "twenty": "", "jps": "They shall all be ashamed of a people that cannot profit them, that are not a help nor profit, but a shame, and also a reproach.", "acv": "They shall all be ashamed because of a people who cannot profit them, who are not a help nor profit, but a shame, and also a reproach.", "anderson": "", "haweis": "", "noyes": "But they are all ashamed of a people that do not profit them; That are no help and no profit, But only a shame and a reproach.", "webster": "They were all ashamed of a people [that] could not profit them, nor be a help nor profit, but a shame, and also a reproach.", "vulgate": "omnes confusi sunt super populo qui eis prodesse non potuit non fuerunt in auxilium et in aliquam utilitatem sed in confusionem et obprobrium;", "brenton": "In vain shall they labour in seeking to a people, which shall not profit them for help, but shall be for a shame and reproach."}}, {"v": 6, "ref": "30:6", "o": "מַשָּׂ֖א בַּהֲמ֣וֹת נֶ֑גֶב בְּ/אֶרֶץ֩ צָרָ֨ה וְ/צוּקָ֜ה לָבִ֧יא וָ/לַ֣יִשׁ מֵ/הֶ֗ם אֶפְעֶה֙ וְ/שָׂרָ֣ף מְעוֹפֵ֔ף יִשְׂאוּ֩ עַל כֶּ֨תֶף עֲיָרִ֜ים חֵֽילֵ/הֶ֗ם וְ/עַל דַּבֶּ֤שֶׁת גְּמַלִּים֙ אֽוֹצְרֹתָ֔/ם עַל עַ֖ם לֹ֥א יוֹעִֽילוּ", "en": {"kjv": "The burden of the beasts of the south: into the land of trouble and anguish, from whence come the young and old lion, the viper and fiery flying serpent, they will carry their riches upon the shoulders of young asses, and their treasures upon the bunches of camels, to a people that shall not profit them.", "web": "The burden of the animals of the South. Through the land of trouble and anguish, of the lioness and the lion, the viper and fiery flying serpent, they carry their riches on the shoulders of young donkeys, and their treasures on the humps of camels, to an unprofitable people.", "bsb": "This is the burden against the beasts of the Negev: Through a land of hardship and distress, of lioness and lion, of viper and flying serpent, they carry their wealth on the backs of donkeys and their treasures on the humps of camels, to a people of no profit to them.", "asv": "The burden of the beasts of the South. Through the land of trouble and anguish, from whence come the lioness and the lion, the viper and fiery flying serpent, they carry their riches upon the shoulders of young asses, and their treasures upon the humps of camels, to a people that shall not profit them.", "ylt": "The burden of the beasts of the south. Into a land of adversity and distress, Of young lion and of old lion, Whence are viper and flying saraph, They carry on the shoulder of asses their wealth, And on the hump of camels their treasures, Unto a people not profitable.", "dra": "The burden of the beasts of the south. In a land of trouble and distress, from whence come the lioness, and the lion, the viper and the flying basilisk, they carry their riches upon the shoulders of beasts, and their treasures upon the bunches of camels to a people that shall not be able to profit them.", "bbe": "The word about the Beasts of the South. Through the land of trouble and grief, the land of the she-lion and the voice of the lion, of the snake and the burning winged snake, they take their wealth on the backs of young asses, and their stores on camels, to a people in whom is no profit.", "geneva": "The burden of the beasts of the South, in a land of trouble and anguish, from whence shall come the yong and olde lyon, the viper and fierie flying serpent against them that shall beare their riches vpon the shoulders of the coltes, and their treasures vpon the bounches of the camels, to a people that cannot profite.", "wycliffe": "The birthun of werk beestis of the south. In the lond of tribulacioun and of angwisch, a lionesse, and a lioun, of hem a serpent, and a cocatrice; thei weren berynge her richessis on the schuldris of werk beestis, and her tresours on the botche of camels, to a puple that myyte not profite to hem.", "rotherham": "The Oracle on the Beasts of the South,—Through a land of distress and oppression—Lioness and lion coming therefrom, Viper and fiery flying serpent, They would carry, on the shoulders of young asses their wealth And on the humps of camels their treasures Unto a people that cannot serve them.", "darby": "— The burden of the beasts of the south: Through a land of trouble and anguish, whence come the lioness and lion, the viper and fiery flying serpent, they carry their riches upon the shoulders of asses, and their treasures upon the bunches of camels, to the people that shall not profit [them].", "twenty": "", "jps": "The burden of the beasts of the South. Through the land of trouble and anguish, from whence come the lioness and the lion, the viper and flying serpent, they carry their riches upon the shoulders of young asses, and their treasures upon the humps of camels, to a people that shall not profit them.", "acv": "The burden of the beasts of the South. Through the land of trouble and anguish, from where come the lioness and the lion, the viper and fiery flying serpent, they carry their riches upon the shoulders of young donkeys, and their treasures upon the humps of camels, to a people who shall not profit them.", "anderson": "", "haweis": "", "noyes": "The loaded beasts go southward. Through a land of anguish and distress, Whence come forth the lioness, and the fierce lion, The viper, and the flying fiery serpent; On the shoulders of young asses they carry their wealth, And on the bunches of camels their treasures, To a people that will not profit them!", "webster": "The burden of the beasts of the south: into the land of trouble and anguish, from whence [come] the young and the old lion, the viper and flying serpent, they will carry their riches upon the shoulders of young asses, and their treasures upon the bunches of camels, to a people [that] shall not profit [them].", "vulgate": "onus iumentorum austri in terra tribulationis et angustiae leaena et leo ex eis vipera et regulus volans portantes super umeros iumentorum divitias suas et super gibbum camelorum thesauros suos ad populum qui eis prodesse non poterit;", "brenton": "THE VISION OF THE QUADRUPEDS IN THE DESERT. In affliction and distress, where are the lion and lion's whelp, thence come also asps, and the young of flying asps, there shall they be who bore their wealth on asses and camels to a nation which shall not profit them."}}, {"v": 7, "ref": "30:7", "o": "וּ/מִצְרַ֕יִם הֶ֥בֶל וָ/רִ֖יק יַעְזֹ֑רוּ לָ/כֵן֙ קָרָ֣אתִי לָ/זֹ֔את רַ֥הַב הֵ֖ם שָֽׁבֶת", "en": {"kjv": "For the Egyptians shall help in vain, and to no purpose: therefore have I cried concerning this, Their strength is to sit still.", "web": "For Egypt helps in vain, and to no purpose; therefore have I called her Rahab who sits still.", "bsb": "Egypt’s help is futile and empty; therefore I have called her Rahab Who Sits Still.", "asv": "For Egypt helpeth in vain, and to no purpose: therefore have I called her Rahab that sitteth still.", "ylt": "Yea, Egyptians are vanity, and in vain do help, Therefore I have cried concerning this: `Their strength is to sit still.'", "dra": "For Egypt shall help in vain, and to no purpose: therefore have I cried concerning this: It is pride only, sit still.", "bbe": "For there is no use or purpose in the help of Egypt: so I have said about her, She is Rahab, who has come to an end.", "geneva": "For the Egyptians are vanitie, and they shall helpe in vaine. Therefore haue I cried vnto her, Their strength is to sit still.", "wycliffe": "For whi Egipt schal helpe in veyn, and idili. Therfor Y criede on this thing, It is pride oneli; ceesse thou.", "rotherham": "But, the Egyptians, with vanity and emptiness, would help,—Therefore have I proclaimed concerning this, Insolent, they sit still!", "darby": "For Egypt shall help in vain, and to no purpose; therefore have I named her, Arrogance, that doeth nothing.", "twenty": "", "jps": "For Egypt helpeth in vain, and to no purpose; therefore have I called her arrogancy that sitteth still.", "acv": "For Egypt helps in vain, and to no purpose. Therefore I have called her Rahab who sits still.", "anderson": "", "haweis": "", "noyes": "Vain and empty is the help of Egypt; Wherefore I call her, The Blusterer that sitteth still.", "webster": "For the Egyptian shall help in vain, and to no purpose: therefore have I cried concerning this, Their strength [is] to sit still.", "vulgate": "Aegyptus enim frustra et vane auxiliabitur ideo clamavi super hoc superbia tantum est quiesce;", "brenton": "The Egyptians shall help you utterly in vain: tell them, This your consolation is vain."}}, {"v": 8, "ref": "30:8", "o": "עַתָּ֗ה בּ֣וֹא כָתְבָ֥/הּ עַל ל֛וּחַ אִתָּ֖/ם וְ/עַל סֵ֣פֶר חֻקָּ֑/הּ וּ/תְהִי֙ לְ/י֣וֹם אַחֲר֔וֹן לָ/עַ֖ד עַד עוֹלָֽם", "en": {"kjv": "Now go, write it before them in a table, and note it in a book, that it may be for the time to come for ever and ever:", "web": "Now go, write it before them on a tablet, and inscribe it in a book, that it may be for the time to come forever and ever.", "bsb": "Go now, write it on a tablet in their presence and inscribe it on a scroll; it will be for the days to come, a witness forever and ever.", "asv": "Now go, write it before them on a tablet, and inscribe it in a book, that it may be for the time to come for ever and ever.", "ylt": "No, go in, write it on a tablet with them, And on a book engrave it, And it is for a latter day, for a witness unto the age,", "dra": "Now therefore go in and write for them upon box, and note it diligently in a book, and it shall be in the latter days for a testimony for ever.", "bbe": "Now go, put it in writing before them on a board, and make a record of it in a book, so that it may be for the future, a witness for all time to come.", "geneva": "Now go, and write it before them in a table, and note it in a booke that it may be for the last day for euer and euer:", "wycliffe": "Now therfor entre thou, and write to it on box, and write thou it diligentli in a book; and it schal be in the last dai in to witnessyng, til in to with outen ende.", "rotherham": "Now, enter—Write it upon a tablet before them And upon a scroll, inscribe it,—That it may serve for a later day, For futurity, unto times age-abiding:—", "darby": "Now go, write it before them on a tablet, and record it in a book, that it may be for the time to come, as a witness for ever,", "twenty": "", "jps": "Now go, write it before them on a tablet, and inscribe it in a book, that it may be for the time to come for ever and ever.", "acv": "Now go, write it before them on a tablet, and inscribe it on a scroll, that it may be for the time to come forever and ever.", "anderson": "", "haweis": "", "noyes": "Go now, write this on a tablet before them; Note it down upon a book, That it may remain for future times, A testimony forever!", "webster": "Now go, write it before them in a table, and note it in a book, that it may be for the time to come for ever and ever:", "vulgate": "nunc ingressus scribe eis super buxum et in libro diligenter exara illud et erit in die novissimo in testimonium usque ad aeternum;", "brenton": "Now then sit down and write these words on a tablet, and in a book; for these things shall be for many long days, and even for ever."}}, {"v": 9, "ref": "30:9", "o": "כִּ֣י עַ֤ם מְרִי֙ ה֔וּא בָּנִ֖ים כֶּחָשִׁ֑ים בָּנִ֕ים לֹֽא אָב֥וּ שְׁמ֖וֹעַ תּוֹרַ֥ת יְהוָֽה", "en": {"kjv": "That this is a rebellious people, lying children, children that will not hear the law of the Lord:", "web": "For it is a rebellious people, lying children, children who will not hear Yahweh’s law;", "bsb": "These are rebellious people, deceitful children, children unwilling to obey the LORD’s instruction.", "asv": "For it is a rebellious people, lying children, children that will not hear the law of Jehovah;", "ylt": "That a rebellious people is this, sons--liars, Sons not willing to hear the law of Jehovah.", "dra": "For it is a people that provoketh to wrath, and lying children that will not hear the law of God.", "bbe": "For they are an uncontrolled people, false-hearted, who will not give ear to the teaching of the Lord:", "geneva": "That it is a rebellious people, lying children, and children that would not heare the law of the Lord.", "wycliffe": "For it is a puple terrynge to wrathfulnesse, and sones lieris, sones that nylen here the lawe of God.", "rotherham": "That it is, a rebellious people, Sons apt at deceiving,—Sons unwilling to hear the law of Yahweh:", "darby": "that this is a rebellious people, lying children, children that will not hear the law of Jehovah;", "twenty": "", "jps": "For it is a rebellious people, lying children, children that refuse to hear the teaching of HaShem;", "acv": "For it is a rebellious people, lying sons, sons who will not hear the law of Jehovah,", "anderson": "", "haweis": "", "noyes": "For this is a rebellious people, false children; Children who will not hear the law of Jehovah;", "webster": "That this [is] a rebellious people, lying children, children [that] will not hear the law of the LORD:", "vulgate": "populus enim ad iracundiam provocans est et filii mendaces filii nolentes audire legem Domini;", "brenton": "For the people is disobedient, false children, who would not hear the law of God:"}}, {"v": 10, "ref": "30:10", "o": "אֲשֶׁ֨ר אָמְר֤וּ לָֽ/רֹאִים֙ לֹ֣א תִרְא֔וּ וְ/לַ֣/חֹזִ֔ים לֹ֥א תֶחֱזוּ לָ֖/נוּ נְכֹח֑וֹת דַּבְּרוּ לָ֣/נוּ חֲלָק֔וֹת חֲז֖וּ מַהֲתַלּֽוֹת", "en": {"kjv": "Which say to the seers, See not; and to the prophets, Prophesy not unto us right things, speak unto us smooth things, prophesy deceits:", "web": "who tell the seers, “Don’t see!” and to the prophets, “Don’t prophesy to us right things. Tell us pleasant things. Prophesy deceits.", "bsb": "They say to the seers, “Stop seeing visions!” and to the prophets, “Do not prophesy to us the truth! Speak to us pleasant words; prophesy illusions.", "asv": "that say to the seers, See not; and to the prophets, Prophesy not unto us right things, speak unto us smooth things, prophesy deceits,", "ylt": "Who have said to seers, `Ye do not see,' And to prophets, `Ye do not prophesy to us Straightforward things, Speak to us smooth things, prophesy deceits,", "dra": "Who say to the seers: See not: and to them that behold: Behold not for us those things that are right: speak unto us pleasant things, see errors for us.", "bbe": "Who say to the seers, See not; and to the prophets, Do not give us word of what is true, but say false things to give us pleasure:", "geneva": "Which say vnto the Seers, See not: and to the Prophets, Prophecie not vnto vs right things: but speake flattering things vnto vs: prophecie errours.", "wycliffe": "Whiche seien to profetis, Nyle ye prophesie; and to biholderis, Nyle ye biholde to vs tho thingis that ben riytful; speke ye thingis plesynge to vs, se ye errouris to vs.", "rotherham": "Who have said to the seers, Ye must not see! To the prophets, Ye must not prophesy to us reproofs! Speak to us smooth things, Prophesy delusions:", "darby": "who say to the seers, See not; and to the prophets, Prophesy not unto us right things; speak unto us smooth things, prophesy deceits;", "twenty": "", "jps": "That say to the seers: 'See not,' and to the prophets: 'Prophesy not unto us right things, speak unto us smooth things, prophesy delusions;", "acv": "who say to the seers, Do not see, and to the prophets, Do not prophesy to us right things. Speak to us smooth things. Prophesy deceits.", "anderson": "", "haweis": "", "noyes": "Who say to the seers, \"See not!\" And to the prophets, \"Prophesy not right things; Speak to us smooth things, Prophesy falsehood!", "webster": "Who say to the seers, See not; and to the prophets, Prophesy not to us right things, speak to us smooth things, prophesy deceits:", "vulgate": "qui dicunt videntibus nolite videre et aspicientibus nolite aspicere nobis ea quae recta sunt loquimini nobis placentia videte nobis errores;", "brenton": "who say to the prophets, Report not to us; and to them that see visions, Speak them not to us, but speak and report to us another error;"}}, {"v": 11, "ref": "30:11", "o": "ס֚וּרוּ מִנֵּי דֶ֔רֶךְ הַטּ֖וּ מִנֵּי אֹ֑רַח הַשְׁבִּ֥יתוּ מִ/פָּנֵ֖י/נוּ אֶת קְד֥וֹשׁ יִשְׂרָאֵֽל", "en": {"kjv": "Get you out of the way, turn aside out of the path, cause the Holy One of Israel to cease from before us.", "web": "Get out of the way. Turn aside from the path. Cause the Holy One of Israel to cease from before us.”", "bsb": "Get out of the way; turn off the road. Rid us of the Holy One of Israel!”", "asv": "get you out of the way, turn aside out of the path, cause the Holy One of Israel to cease from before us.", "ylt": "Turn aside from the way, decline from the path, Cause to cease from before us the Holy One of Israel.'", "dra": "Take away from me the way, turn away the path from me, let the Holy One of Israel cease from before us.", "bbe": "Get out of the good way, turning from the right road; do not keep the Holy One of Israel before our minds.", "geneva": "Depart out of the way: go aside out of the path: cause the holy one of Israel to cease from vs.", "wycliffe": "Do ye awei fro me the weie, bowe ye awei fro me the path; the hooli of Israel ceesse fro oure face.", "rotherham": "Depart ye from the way, Turn aside from the path,—Desist from setting before us the Holy One of Israel.", "darby": "get you out of the way, turn aside out of the path, cause the Holy One of Israel to cease from before us!", "twenty": "", "jps": "Get you out of the way, turn aside out of the path, cause the Holy One of Israel to cease from before us.'", "acv": "Get you out of the way. Turn aside out of the path. Cause the Holy One of Israel to cease from before us.", "anderson": "", "haweis": "", "noyes": "Turn aside from the way, Depart from the path, Remove from our sight the Holy One of Israel!\"", "webster": "Withdraw from the way, turn aside from the path, cause the Holy One of Israel to cease from before us.", "vulgate": "auferte a me viam declinate a me semitam cesset a facie nostra Sanctus Israhel;", "brenton": "and turn us aside from this way; remove from us this path, and remove from us the oracle of Israel."}}, {"v": 12, "ref": "30:12", "o": "לָ/כֵ֗ן כֹּ֤ה אָמַר֙ קְד֣וֹשׁ יִשְׂרָאֵ֔ל יַ֥עַן מָֽאָסְ/כֶ֖ם בַּ/דָּבָ֣ר הַ/זֶּ֑ה וַֽ/תִּבְטְחוּ֙ בְּ/עֹ֣שֶׁק וְ/נָל֔וֹז וַ/תִּֽשָּׁעֲנ֖וּ עָלָֽי/ו", "en": {"kjv": "Wherefore thus saith the Holy One of Israel, Because ye despise this word, and trust in oppression and perverseness, and stay thereon:", "web": "Therefore thus says the Holy One of Israel, “Because you despise this word, and trust in oppression and perverseness, and rely on it;", "bsb": "Therefore this is what the Holy One of Israel says: “Because you have rejected this message, trusting in oppression and relying on deceit,", "asv": "Wherefore thus saith the Holy One of Israel, Because ye despise this word, and trust in oppression and perverseness, and rely thereon;", "ylt": "Therefore, thus said the Holy One of Israel, Because of your kicking against this word, And ye trust in oppression, And perverseness, and rely on it,", "dra": "Therefore thus saith the Holy One of Israel: Because you have rejected this word, and have trusted in oppression and tumult, and have leaned upon it:", "bbe": "For this cause the Holy One of Israel says, Because you will not give ear to this word, and are looking for help in ways of deceit and evil, and are putting your hope in them:", "geneva": "Therefoe thus saith the holy one of Israel, Because you haue cast off this worde, and trust in violence, and wickednes, and stay thereupon,", "wycliffe": "Therfor the hooli of Israel seith these thingis, For that that ye repreuiden this word, and hopiden on fals caleng, and on noise, and tristiden on it,", "rotherham": "Therefore—Thus, saith the Holy One of Israel, Because ye have rejected this word,—And have trusted in oppression and perverseness, And have relied thereon,", "darby": "Therefore thus saith the Holy One of Israel: Because ye reject this word, and confide in oppression and wilfulness, and depend thereon,", "twenty": "", "jps": "Wherefore thus saith the Holy One of Israel: because ye despise this word, and trust in oppression and perverseness, and stay thereon;", "acv": "Therefore thus says the Holy One of Israel, Because ye despise this word, and trust in oppression and perverseness, and rely on it,", "anderson": "", "haweis": "", "noyes": "Wherefore thus saith the Holy One of Israel: Since ye despise this word, And trust in oppression and perverseness, And lean thereon,", "webster": "Wherefore thus saith the Holy One of Israel, Because ye despise this word, and trust in oppression and perverseness, and lean upon it:", "vulgate": "propterea haec dicit Sanctus Israhel pro eo quod reprobastis verbum hoc et sperastis in calumniam et tumultum et innixi estis super eo;", "brenton": "Therefore thus saith the Holy One of Israel, Because ye have refused to obey these words, and have trusted in falsehood; and because thou hast murmured, and been confident in this respect:"}}, {"v": 13, "ref": "30:13", "o": "לָ/כֵ֗ן יִֽהְיֶ֤ה לָ/כֶם֙ הֶ/עָוֺ֣ן הַ/זֶּ֔ה כְּ/פֶ֣רֶץ נֹפֵ֔ל נִבְעֶ֖ה בְּ/חוֹמָ֣ה נִשְׂגָּבָ֑ה אֲשֶׁר פִּתְאֹ֥ם לְ/פֶ֖תַע יָב֥וֹא שִׁבְרָֽ/הּ", "en": {"kjv": "Therefore this iniquity shall be to you as a breach ready to fall, swelling out in a high wall, whose breaking cometh suddenly at an instant.", "web": "therefore this iniquity shall be to you like a breach ready to fall, swelling out in a high wall, whose breaking comes suddenly in an instant.", "bsb": "this iniquity of yours is like a breach about to fail, a bulge in a high wall, whose collapse will come suddenly— in an instant!", "asv": "therefore this iniquity shall be to you as a breach ready to fall, swelling out in a high wall, whose breaking cometh suddenly in an instant.", "ylt": "Therefore is this iniquity to you as a breach falling, Swelled out in a wall set on high, Whose destruction suddenly, at an instant cometh.", "dra": "Therefore shall this iniquity be to you as a breach that falleth, and is found wanting in a high wall, for the destruction thereof shall come on a sudden, when it is not looked for.", "bbe": "This sin will be to you like a crack in a high wall, causing its fall suddenly and in a minute.", "geneva": "Therefore this iniquitie shalbe vnto you as a breach that falleth, or a swelling in an hie wall, whose breaking commeth suddenly in a moment.", "wycliffe": "therfor this wickidnesse schal be to you as a brekyng fallynge doun, and souyt in an hiy wal; for sudeynli while it is not hopid, the brekyng therof schal come.", "rotherham": "Therefore, shall this iniquity become to you As a breach ready to fall, A bulging in a high wall,—Whose breaking down cometh, suddenly in a twinkling.", "darby": "therefore this iniquity shall be to you as a breach ready to fall, swelling out in a towering wall, whose breaking shall come suddenly in an instant.", "twenty": "", "jps": "Therefore this iniquity shall be to you as a breach ready to fall, swelling out in a high wall, whose breaking cometh suddenly at an instant.", "acv": "therefore this iniquity shall be to you as a breach ready to fall, swelling out in a high wall, whose breaking comes suddenly in an instant.", "anderson": "", "haweis": "", "noyes": "Therefore shall this iniquity be to you Like a breach ready to give way, That swelleth out in a high wall, Whose fall cometh suddenly, in an instant.", "webster": "Therefore this iniquity shall be to you as a breach ready to fall, swelling out in a high wall, whose breaking cometh suddenly at an instant.", "vulgate": "propterea erit vobis iniquitas haec sicut interruptio cadens et requisita in muro excelso quoniam subito dum non speratur veniet contritio eius;", "brenton": "therefore shall this sin be to you as a wall suddenly falling when a strong city has been taken, of which the fall is very near at hand."}}, {"v": 14, "ref": "30:14", "o": "וּ֠/שְׁבָרָ/הּ כְּ/שֵׁ֨בֶר נֵ֧בֶל יוֹצְרִ֛ים כָּת֖וּת לֹ֣א יַחְמֹ֑ל וְ/לֹֽא יִמָּצֵ֤א בִ/מְכִתָּת/וֹ֙ חֶ֔רֶשׂ לַ/חְתּ֥וֹת אֵשׁ֙ מִ/יָּק֔וּד וְ/לַ/חְשֹׂ֥ף מַ֖יִם מִ/גֶּֽבֶא", "en": {"kjv": "And he shall break it as the breaking of the potters’ vessel that is broken in pieces; he shall not spare: so that there shall not be found in the bursting of it a sherd to take fire from the hearth, or to take water withal out of the pit.", "web": "He will break it as a potter’s vessel is broken, breaking it in pieces without sparing, so that there won’t be found among the broken piece a piece good enough to take fire from the hearth, or to dip up water out of the cistern.”", "bsb": "It will break in pieces like a potter’s jar, shattered so that no fragment can be found. Not a shard will be found in the dust large enough to scoop the coals from a hearth or to skim the water from a cistern.”", "asv": "And he shall break it as a potter’s vessel is broken, breaking it in pieces without sparing; so that there shall not be found among the pieces thereof a sherd wherewith to take fire from the hearth, or to dip up water out of the cistern.", "ylt": "And He hath broken it As the breaking of the potters' bottle, Beaten down--He doth not spare, Nor is there found, in its beating down, A potsherd to take fire from the burning, And to draw out waters from a ditch.", "dra": "And it shall be broken small, as the potter's vessel is broken all to pieces with mighty breaking, and there shall not a sherd be found of the pieces thereof, wherein a little fire may be carried from the hearth, or a little water be drawn out of the pit.", "bbe": "And he will let it be broken as a potter's vessel is broken: it will be smashed to bits without mercy; so that there will not be a bit in which one may take fire from the fireplace, or water from the spring.", "geneva": "And the breaking thereof is like the breaking of a potters pot, which is broken without pitie, and in the breaking thereof is not found a sheard to take fire out of the hearth, or to take water out of the pit.", "wycliffe": "And it schal be maad lesse, as a galoun of a pottere is brokun with ful strong brekyng; and a scherd schal not be foundun of the gobetis therof, in which scherd a litil fier schal be borun of brennyng, ethir a litil of watir schal be drawun of the diche.", "rotherham": "Yea he will break it—as the breaking of the pitcher of a potter, crushed, he will not spare; So that there shall not be found when it is smashed, A sherd wherewith to snatch fire from a hearth, Or to skim off water out of a cistern.", "darby": "And he shall break it as the breaking of a potter's vessel, that is broken in pieces unsparingly; and in the pieces of it there shall not be found a sherd to take fire from the hearth, or to scoop water out of the cistern.", "twenty": "", "jps": "And He shall break it as a potter's vessel is broken, breaking it in pieces without sparing; so that there shall not be found among the pieces thereof a sherd to take fire from the hearth, or to take water out of the cistern.", "acv": "And he shall break it as a potter's vessel is broken, breaking it in pieces without sparing, so that there shall not be found among the pieces of it a shard with which to take fire from the hearth, or to dip up water out of the cistern.", "anderson": "", "haweis": "", "noyes": "It is broken like a potter’s vessel, Which is dashed in pieces and not spared, So that among its fragments not a sherd is found to take up fire from the hearth, Or to dip water from the cistern.", "webster": "And he shall break it as the breaking of the potter's vessel that is broken in pieces; he shall not spare: so that there shall not be found in the bursting of it a piece to take fire from the hearth, or to take water out of the pit.", "vulgate": "et comminuetur sicut conteritur lagoena figuli contritione pervalida et non invenietur de fragmentis eius testa in qua portetur igniculus de incendio aut hauriatur parum aquae de fovea;", "brenton": "And the fall thereof shall be as the breaking of an earthen vessel, as small fragments of a pitcher, so that thou shouldest not find among them a sherd, with which thou mightest take up fire, and with which thou shouldest draw a little water."}}, {"v": 15, "ref": "30:15", "o": "כִּ֣י כֹֽה אָמַר֩ אֲדֹנָ֨/י יְהוִ֜ה קְד֣וֹשׁ יִשְׂרָאֵ֗ל בְּ/שׁוּבָ֤ה וָ/נַ֨חַת֙ תִּוָּ֣שֵׁע֔וּ/ן בְּ/הַשְׁקֵט֙ וּ/בְ/בִטְחָ֔ה תִּהְיֶ֖ה גְּבֽוּרַתְ/כֶ֑ם וְ/לֹ֖א אֲבִיתֶֽם", "en": {"kjv": "For thus saith the Lord God, the Holy One of Israel; In returning and rest shall ye be saved; in quietness and in confidence shall be your strength: and ye would not.", "web": "For thus said the Lord Yahweh, the Holy One of Israel, “You will be saved in returning and rest. Your strength will be in quietness and in confidence.” You refused,", "bsb": "For the Lord GOD, the Holy One of Israel, has said: “By repentance and rest you would be saved; your strength would lie in quiet confidence— but you were not willing.”", "asv": "For thus said the Lord Jehovah, the Holy One of Israel, In returning and rest shall ye be saved; in quietness and in confidence shall be your strength. And ye would not:", "ylt": "For thus said the Lord Jehovah, The Holy One of Israel: `In returning and rest ye are saved, In keeping quiet and in confidence is your might, And ye have not been willing.", "dra": "For thus saith the Lord God the Holy One of Israel: If you return and be quiet, you shall be saved: in silence and in hope shall your strength be. And you would not:", "bbe": "For the Lord, the Holy One of Israel, said, In quiet and rest is your salvation: peace and hope are your strength: but you would not have it so.", "geneva": "For thus sayd the Lord God, the Holy one of Israel, In rest and quietnes shall ye be saued: in quietnes and in confidence shall be your strength, but ye would not.", "wycliffe": "For whi the Lord God, the hooli of Israel, seith these thingis, If ye turnen ayen, and resten, ye schulen be saaf; in stilnesse and in hope schal be youre strengthe. And ye nolden.", "rotherham": "For thus, said my Lord Yahweh, the Holy One of Israel—By returning and resting, shall ye be saved, In keeping quiet and trusting, shall be your strength,—Howbeit ye would not!", "darby": "For thus saith the Lord Jehovah, the Holy One of Israel: In returning and rest shall ye be saved, in quietness and confidence shall be your strength; but ye would not.", "twenty": "", "jps": "For thus said the L-rd GOD, the Holy One of Israel: in sitting still and rest shall ye be saved, in quietness and in confidence shall be your strength; and ye would not.", "acv": "For thus said the lord Jehovah, the Holy One of Israel, Ye shall be saved in returning and rest. Your strength shall be in quietness and in confidence. And ye would not,", "anderson": "", "haweis": "", "noyes": "For thus said the Lord Jehovah, the Holy One of Israel: By a return and by rest shall ye be saved; In quietness and confidence is your strength;", "webster": "For thus saith the Lord GOD, the Holy One of Israel; In returning and rest shall ye be saved; in quietness and in confidence shall be your strength: and ye would not.", "vulgate": "quia haec dicit Dominus Deus Sanctus Israhel si revertamini et quiescatis salvi eritis in silentio et in spe erit fortitudo vestra et noluistis;", "brenton": "Thus saith the Lord, the Holy Lord of Israel; When thou shalt turn and mourn, then thou shalt be saved; and thou shalt know where thou wast, when thou didst trust in vanities: then your strength became vain, yet ye would not hearken:"}}, {"v": 16, "ref": "30:16", "o": "וַ/תֹּ֨אמְר֥וּ לֹא כִ֛י עַל ס֥וּס נָנ֖וּס עַל כֵּ֣ן תְּנוּס֑וּ/ן וְ/עַל קַ֣ל נִרְכָּ֔ב עַל כֵּ֖ן יִקַּ֥לּוּ רֹדְפֵי/כֶֽם", "en": {"kjv": "But ye said, No; for we will flee upon horses; therefore shall ye flee: and, We will ride upon the swift; therefore shall they that pursue you be swift.", "web": "but you said, “No, for we will flee on horses”; therefore you will flee; and, “We will ride on the swift”; therefore those who pursue you will be swift.", "bsb": "“No,” you say, “we will flee on horses.” Therefore you will flee! “We will ride swift horses,” but your pursuers will be faster.", "asv": "but ye said, No, for we will flee upon horses; therefore shall ye flee: and, We will ride upon the swift; therefore shall they that pursue you be swift.", "ylt": "And ye say, No, for on a horse we flee? Therefore ye flee, And on the swift we ride! Therefore swift are your pursuers.", "dra": "But have said: No, but we will flee to horses: therefore shall you flee. And we will mount upon swift ones: therefore shall they be swifter that shall pursue after you.", "bbe": "Saying, No, for we will go in flight on horses; so you will certainly go in flight: and, We will go on the backs of quick-running beasts; so those who go after you will be quick-footed.", "geneva": "For ye haue sayd, No, but we wil flee away vpon horses. Therefore shall ye flee. We will ride vpon the swiftest. Therefore shall your persecuters be swifter.", "wycliffe": "And ye seiden, Nai, but we schulen fle to horsis; therfor ye schulen fle. And we schulen stie on swifte horsis; therfor thei schulen be swiftere, that schulen pursue you.", "rotherham": "But ye said,—Nay! but on horses, will we flee For this cause, shall ye indeed flee,—And on the swift, will we ride, For this cause, swift, shall be your pursuers:", "darby": "And ye said, No, but we will flee upon horses, — therefore shall ye flee; and, We will ride upon the swift, — therefore shall they that pursue you be swift.", "twenty": "", "jps": "But ye said: 'No, for we will flee upon horses'; therefore shall ye flee; and: 'We will ride upon the swift'; therefore shall they that pursue you be swift.", "acv": "but ye said, No, for we will flee upon horses. Therefore ye shall flee. And ye said, We will ride upon the swift. Therefore those who pursue you shall be swift.", "anderson": "", "haweis": "", "noyes": "But ye would not. Ye said, \"No! we will bound along upon horses\"; Truly ye shall bound along in flight. \"We will ride upon swift coursers\"; But they shall be swift that pursue you.", "webster": "But ye said, No; for we will flee upon horses; therefore shall ye flee: and, We will ride upon the swift; therefore shall they that pursue you be swift.", "vulgate": "et dixistis nequaquam sed ad equos fugiemus ideo fugietis et super veloces ascendemus ideo veloces erunt qui persequentur vos;", "brenton": "but ye said, We will flee upon horses; therefore shall ye flee: and, We will be aided by swift riders; therefore shall they that pursue you be swift."}}, {"v": 17, "ref": "30:17", "o": "אֶ֣לֶף אֶחָ֗ד מִ/פְּנֵי֙ גַּעֲרַ֣ת אֶחָ֔ד מִ/פְּנֵ֛י גַּעֲרַ֥ת חֲמִשָּׁ֖ה תָּנֻ֑סוּ עַ֣ד אִם נוֹתַרְתֶּ֗ם כַּ/תֹּ֨רֶן֙ עַל רֹ֣אשׁ הָ/הָ֔ר וְ/כַ/נֵּ֖ס עַל הַ/גִּבְעָֽה", "en": {"kjv": "One thousand shall flee at the rebuke of one; at the rebuke of five shall ye flee: till ye be left as a beacon upon the top of a mountain, and as an ensign on an hill.", "web": "One thousand will flee at the threat of one. At the threat of five, you will flee until you are left like a beacon on the top of a mountain, and like a banner on a hill.", "bsb": "A thousand will flee at the threat of one; at the threat of five you will all flee, until you are left alone like a pole on a mountaintop, like a banner on a hill.", "asv": "One thousand shall flee at the threat of one; at the threat of five shall ye flee: till ye be left as a beacon upon the top of a mountain, and as an ensign on a hill.", "ylt": "One thousand because of the rebuke of one, Because of the rebuke of five ye flee, Till ye have been surely left as a pole On the top of the mountain, And as an ensign on the height.", "dra": "A thousand men shall flee for fear of one: and for fear of five shall you flee, till you be left as the mast of ship on the top of a mountain, and as an ensign upon a hill.", "bbe": "A thousand will go in fear before one; even before five you will go in flight: till you are like a pillar by itself on the top of a mountain, and like a flag on a hill.", "geneva": "A thousand as one shall flee at the rebuke of one: at the rebuke of fiue shall ye flee, till ye be left as a ship maste vpon the top of a mountaine, and as a beaken vpon an hill.", "wycliffe": "A thousynde men schulen fle fro the face of the drede of oon; and ye schulen fle fro the face of drede of fyue, til ye be left as the mast of a schip in the cop of a munteyn, and as a signe on a litil hil.", "rotherham": "One thousand, before the war-cry of one—before the war-cry of five, shall ye flee,—Until ye have been left, As a pole on the top of a mountain, And as an ensign upon a hill.", "darby": "One thousand [shall flee] at the rebuke of one; at the rebuke of five shall ye flee: till ye be left as a beacon upon the top of a mountain, and as a banner on a hill.", "twenty": "", "jps": "One thousand shall flee at the rebuke of one, at the rebuke of five shall ye flee; till ye be left as a beacon upon the top of a mountain, and as an ensign on a hill.", "acv": "One thousand shall flee at the threat of one. Ye shall flee at the threat of five, till ye are left as a beacon upon the top of a mountain, and as an ensign on a hill.", "anderson": "", "haweis": "", "noyes": "A thousand shall flee at the rebuke of one, And ten thousand at the rebuke of five, Till what remains of you shall be as a beacon on the top of a mountain, As a banner upon a hill.", "webster": "One thousand [shall flee] at the rebuke of one; at the rebuke of five shall ye flee: till ye be left as a beacon upon the top of a mountain, and as an ensign on a hill.", "vulgate": "mille homines a facie terroris unius et a facie terroris quinque fugietis donec relinquamini quasi malus navis in vertice montis et quasi signum super collem;", "brenton": "A thousand shall flee because of the voice of one, and many shall flee on account of the voice of five; until ye be left as a signal-post upon a mountain, and as one bearing an ensign upon a hill."}}, {"v": 18, "ref": "30:18", "o": "וְ/לָ/כֵ֞ן יְחַכֶּ֤ה יְהוָה֙ לַֽ/חֲנַנְ/כֶ֔ם וְ/לָ/כֵ֥ן יָר֖וּם לְ/רַֽחֶמְ/כֶ֑ם כִּֽי אֱלֹהֵ֤י מִשְׁפָּט֙ יְהוָ֔ה אַשְׁרֵ֖י כָּל ח֥וֹכֵי לֽ/וֹ", "en": {"kjv": "And therefore will the Lord wait, that he may be gracious unto you, and therefore will he be exalted, that he may have mercy upon you: for the Lord is a God of judgment: blessed are all they that wait for him.", "web": "Therefore Yahweh will wait, that he may be gracious to you; and therefore he will be exalted, that he may have mercy on you, for Yahweh is a God of justice. Blessed are all those who wait for him.", "bsb": "Therefore the LORD longs to be gracious to you; therefore He rises to show you compassion, for the LORD is a just God. Blessed are all who wait for Him.", "asv": "And therefore will Jehovah wait, that he may be gracious unto you; and therefore will he be exalted, that he may have mercy upon you: for Jehovah is a God of justice; blessed are all they that wait for him.", "ylt": "And therefore doth wait Jehovah to favour you, And therefore He is exalted to pity you, For a God of judgment is Jehovah, O the blessedness of all waiting for Him.", "dra": "Therefore the Lord waiteth that he may have mercy on you: and therefore shall he be exalted sparing you: because the Lord is the God of judgment: blessed are all they that wait for him.", "bbe": "For this cause the Lord will be waiting, so that he may be kind to you; and he will be lifted up, so that he may have mercy on you; for the Lord is a God of righteousness: there is a blessing on all whose hope is in him.", "geneva": "Yet therefore will the Lord waite, that he may haue mercy vpon you, and therefore wil he be exalted, that hee may haue compassion vpon you: for the Lord is the God of iudgement. Blessed are all they that waite for him.", "wycliffe": "Therfor the Lord abidith, that he haue mercy on you, and therfor he schal be enhaunsid sparynge you; for whi God is Lord of doom, blessid ben alle thei that abiden hym.", "rotherham": "And, therefore, will Yahweh wait, That he may grant you favour, And, therefore, will he lift himself up, That he may show you compassion,—For A God of justice, is, Yahweh, How happy all they who are waiting for him", "darby": "And therefore will Jehovah wait, that he may be gracious unto you, and therefore will he lift himself up, that he may have mercy upon you; for Jehovah is aGod of judgment: blessed are all they that wait for him.", "twenty": "", "jps": "And therefore will HaShem wait, that He may be gracious unto you, and therefore will He be exalted, that He may have compassion upon you; for HaShem is a G-d of justice, happy are all they that wait for Him.", "acv": "And therefore Jehovah will wait, that he may be gracious to you. And therefore he will be exalted, that he may have mercy upon you, for Jehovah is a God of justice. Blessed are all those who wait for him.", "anderson": "", "haweis": "", "noyes": "And yet will Jehovah wait to be gracious to you, And yet will he arise to have mercy upon you; For Jehovah is a righteous God; Happy are all they who wait for him!", "webster": "And therefore will the LORD wait, that he may be gracious to you, and therefore will he be exalted, that he may have mercy upon you: for the LORD [is] a God of judgment: blessed [are] all they that wait for him.", "vulgate": "propterea expectat Dominus ut misereatur vestri et ideo exaltabitur parcens vobis quia Deus iudicii Dominus beati omnes qui expectant eum;", "brenton": "And the Lord will again wait, that he may pity you, and will therefore be exalted that he may have mercy upon you: because the Lord your God is a judge: blessed are they that stay themselves upon him."}}, {"v": 19, "ref": "30:19", "o": "כִּי עַ֛ם בְּ/צִיּ֥וֹן יֵשֵׁ֖ב בִּ/ירֽוּשָׁלִָ֑ם בָּכ֣וֹ לֹֽא תִבְכֶּ֗ה חָנ֤וֹן יָחְנְ/ךָ֙ לְ/ק֣וֹל זַעֲקֶ֔/ךָ כְּ/שָׁמְעָת֖/וֹ עָנָֽ/ךְ", "en": {"kjv": "For the people shall dwell in Zion at Jerusalem: thou shalt weep no more: he will be very gracious unto thee at the voice of thy cry; when he shall hear it, he will answer thee.", "web": "For the people will dwell in Zion at Jerusalem. You will weep no more. He will surely be gracious to you at the voice of your cry. When he hears you, he will answer you.", "bsb": "O people in Zion who dwell in Jerusalem, you will weep no more. He will surely be gracious when you cry for help; when He hears, He will answer you.", "asv": "For the people shall dwell in Zion at Jerusalem; thou shalt weep no more; he will surely be gracious unto thee at the voice of thy cry; when he shall hear, he will answer thee.", "ylt": "For the people in Zion dwell in Jerusalem, Weep thou not, weeping, Pitying, He pitieth thee at the voice of thy cry, When He heareth He answereth thee.", "dra": "For the people of Sion shall dwell in Jerusalem: weeping thou shalt not weep, he will surely have pity on thee: at the voice of thy cry, as soon as he shall hear, he will answer thee.", "bbe": "O people, living in Zion, at Jerusalem, your weeping will be ended; he will certainly have mercy on you at the sound of your cry; when it comes to his ear, he will give you an answer.", "geneva": "Surely a people shall dwell in Zion, and in Ierusalem: thou shalt weepe no more: he wil certainly haue mercy vpon thee at the voyce of thy crye: when he heareth thee, he wil answere thee.", "wycliffe": "Forsothe the puple of Sion schal dwelle in Jerusalem; thou wepynge schal not wepe, he doynge merci schal haue merci on thee; at the vois of thi cry, anoon as he herith, he schal answere to thee.", "rotherham": "For, a people, In Zion, shall dwell, In Jerusalem,—As for weeping, thou shalt not weep! As for favour, he will grant thee favour, at the sound of thine outcry,—As soon as he heareth, he hath answered thee!", "darby": "For the people shall dwell in Zion, at Jerusalem. Thou shalt weep no more; he will be very gracious unto thee at the voice of thy cry; as he heareth it, he will answer thee.", "twenty": "", "jps": "For, O people that dwellest in Zion at Jerusalem, thou shalt weep no more; He will surely be gracious unto thee at the voice of thy cry, when He shall hear, He will answer thee.", "acv": "For the people shall dwell in Zion at Jerusalem. Thou shall weep no more. He will surely be gracious to thee at the voice of thy cry. When he shall hear, he will answer thee.", "anderson": "", "haweis": "", "noyes": "For, O people of Zion, that dwellest in Jerusalem, Thou shalt not always weep! He will be very gracious to thee at the voice of thy cry; No sooner shall he hear it, than he will answer thee.", "webster": "For the people shall dwell in Zion at Jerusalem: thou shalt weep no more: he will be very gracious to thee at the voice of thy cry; when he shall hear it, he will answer thee.", "vulgate": "populus enim Sion habitabit in Hierusalem plorans nequaquam plorabis miserans miserebitur tui ad vocem clamoris tui statim ut audierit respondebit tibi;", "brenton": "For the holy people shall dwell in Sion: and whereas Jerusalem has wept bitterly, saying, Pity me; he shall pity thee: when he perceived the voice of thy cry, he hearkened to thee."}}, {"v": 20, "ref": "30:20", "o": "וְ/נָתַ֨ן לָ/כֶ֧ם אֲדֹנָ֛/י לֶ֥חֶם צָ֖ר וּ/מַ֣יִם לָ֑חַץ וְ/לֹֽא יִכָּנֵ֥ף עוֹד֙ מוֹרֶ֔י/ךָ וְ/הָי֥וּ עֵינֶ֖י/ךָ רֹא֥וֹת אֶת מוֹרֶֽי/ךָ", "en": {"kjv": "And though the Lord give you the bread of adversity, and the water of affliction, yet shall not thy teachers be removed into a corner any more, but thine eyes shall see thy teachers:", "web": "Though the Lord may give you the bread of adversity and the water of affliction, yet your teachers won’t be hidden any more, but your eyes will see your teachers;", "bsb": "The Lord will give you the bread of adversity and the water of affliction, but your Teacher will no longer hide Himself—with your own eyes you will see Him.", "asv": "And though the Lord give you the bread of adversity and the water of affliction, yet shall not thy teachers be hidden anymore, but thine eyes shall see thy teachers;", "ylt": "And the Lord hath given to you bread of adversity, And water of oppression. And thy directors remove no more, And thine eyes have seen thy directors,", "dra": "And the Lord will give you spare bread, and short water: and will not cause thy teacher to flee away from thee any more, and thy eyes shall see thy teacher.", "bbe": "And though the Lord will give you the bread of trouble and the water of grief, you will no longer put your teacher on one side, but you will see your teacher:", "geneva": "And when the Lord hath giuen you the bread of aduersitie, and the water of affliction, thy raine shalbe no more kept backe, but thine eyes shall see thy raine.", "wycliffe": "And the Lord schal yyue to thee streyt breed, and schort watir, and schal no more make thi techere to fle awei fro thee; and thin iyen schulen be seynge thi comaundour,", "rotherham": "Though My Lord, should give you bread in short measure and water in scant allowance Yet will thy Teacher not hide himself any more, But thine eyes shall ever be looking on thy Teacher.", "darby": "And the Lord will give you the bread of adversity, and the water of oppression; yet thy teachers shall not be hidden any more, but thine eyes shall see thy teachers.", "twenty": "", "jps": "And though the L-rd give you sparing bread and scant water, yet shall not thy Teacher hide Himself any more, but thine eyes shall see thy Teacher;", "acv": "And though the Lord give you the bread of adversity and the water of affliction, yet thy teachers shall not be hidden anymore, but thine eyes shall see thy teachers.", "anderson": "", "haweis": "", "noyes": "Though Jehovah hath given thee the bread of distress, and the water of affliction, Yet shall thy teachers be hidden from thee no more; But thine eyes shall see thy teachers.", "webster": "And [though] the Lord shall give you the bread of adversity, and the water of affliction, yet shall not thy teachers be removed into a corner any more, but thy eyes shall see thy teachers:", "vulgate": "et dabit vobis Dominus panem artum et aquam brevem et non faciet avolare a te ultra doctorem tuum et erunt oculi tui videntes praeceptorem tuum;", "brenton": "And though the Lord shall give you the bread of affliction and scant water, yet they that cause thee to err shall no more at all draw nigh to thee; for thine eyes shall see those that cause thee to err,"}}, {"v": 21, "ref": "30:21", "o": "וְ/אָזְנֶ֨י/ךָ֙ תִּשְׁמַ֣עְנָה דָבָ֔ר מֵֽ/אַחֲרֶ֖י/ךָ לֵ/אמֹ֑ר זֶ֤ה הַ/דֶּ֨רֶךְ֙ לְכ֣וּ ב֔/וֹ כִּ֥י תַאֲמִ֖ינוּ וְ/כִ֥י תַשְׂמְאִֽילוּ", "en": {"kjv": "And thine ears shall hear a word behind thee, saying, This is the way, walk ye in it, when ye turn to the right hand, and when ye turn to the left.", "web": "and when you turn to the right hand, and when you turn to the left, your ears will hear a voice behind you, saying, “This is the way. Walk in it.”", "bsb": "And whether you turn to the right or to the left, your ears will hear this command behind you: “This is the way. Walk in it.”", "asv": "and thine ears shall hear a word behind thee, saying, This is the way, walk ye in it; when ye turn to the right hand, and when ye turn to the left.", "ylt": "And thine ear heareth a word behind thee, Saying, `This is the way, go ye in it,' When ye turn to the right, And when ye turn to the left.", "dra": "And thy ears shall hear the word of one admonishing thee behind thy back: This is the way, walk ye in it: and go not aside neither to the right hand, nor to the left.", "bbe": "And at your back, when you are turning to the right hand or to the left, a voice will be sounding in your ears, saying, This is the way in which you are to go.", "geneva": "And thine eares shall heare a worde behind thee, saying, This is the way, walke ye in it, when thou turnest to the right hand, and when thou turnest to the left.", "wycliffe": "and thin eeris schulen here a word bihynde the bak of hym that monestith; This is the weie, go ye therynne, nether to the riyt half nether to the left half.", "rotherham": "So shall, thine own ears, hear a word from behind thee saying,—This, is the way, walk ye therein, When ye would turn to the right hand Or when ye would turn to the left.", "darby": "And when ye turn to the right hand or when ye turn to the left, thine ears shall hear a word behind thee, saying, This is the way, walk ye in it.", "twenty": "", "jps": "And thine ears shall hear a word behind thee, saying: 'This is the way, walk ye in it, when ye turn to the right hand, and when ye turn to the left.'", "acv": "And thine ears shall hear a word behind thee, saying, This is the way, walk ye in it when ye turn to the right hand, and when ye turn to the left.", "anderson": "", "haweis": "", "noyes": "And thine ears shall hear a voice behind thee, Saying, \"This is the way, walk ye in it!\" When ye turn aside to the right hand, or to the left.", "webster": "And thy ears shall hear a word behind thee, saying, This [is] the way, walk ye in it, when ye turn to the right hand, and when ye turn to the left.", "vulgate": "et aures tuae audient verbum post tergum monentis haec via ambulate in ea neque ad dexteram neque ad sinistram;", "brenton": "and thine ears shall hear the words of them that went after thee to lead thee astray, who say, This is the way, let us walk in it, whether to the right or to the left."}}, {"v": 22, "ref": "30:22", "o": "וְ/טִמֵּאתֶ֗ם אֶת צִפּוּי֙ פְּסִילֵ֣י כַסְפֶּ֔/ךָ וְ/אֶת אֲפֻדַּ֖ת מַסֵּכַ֣ת זְהָבֶ֑/ךָ תִּזְרֵ/ם֙ כְּמ֣וֹ דָוָ֔ה צֵ֖א תֹּ֥אמַר לֽ/וֹ", "en": {"kjv": "Ye shall defile also the covering of thy graven images of silver, and the ornament of thy molten images of gold: thou shalt cast them away as a menstruous cloth; thou shalt say unto it, Get thee hence.", "web": "You shall defile the overlaying of your engraved images of silver, and the plating of your molten images of gold. You shall cast them away as an unclean thing. You shall tell it, “Go away!”", "bsb": "So you will desecrate your silver-plated idols and your gold-plated images. You will throw them away like menstrual cloths, saying to them, “Be gone!”", "asv": "And ye shall defile the overlaying of thy graven images of silver, and the plating of thy molten images of gold: thou shalt cast them away as an unclean thing; thou shalt say unto it, Get thee hence.", "ylt": "And ye have defiled the covering of Thy graven images of silver, And the ephod of thy molten image of gold, Thou scatterest them as a sickening thing, `Go out,' thou sayest to it.", "dra": "And thou shalt defile the plates of thy graven things of silver, and the garment of thy molten things of gold, and shalt cast them away as the uncleanness of a menstruous woman. Thou shalt say to it: Get thee hence.", "bbe": "And you will make unclean what is covering your pictured images of silver, and the plating of your images of gold: you will send them away as an unclean thing, saying, Be gone!", "geneva": "And ye shall pollute the couering of the images of siluer, and the riche ornament of thine images of golde, and cast them away as a menstruous cloth, and thou shalt say vnto it, Get thee hence.", "wycliffe": "And thou schalt defoule the platis of the grauun ymagis of thi siluer, and the cloth of the yotun ymage of thi gold; and thou schalt scatere tho, as the vnclennesse of a womman in vncleene blood; Go thou out, and thou schalt seie to it.", "rotherham": "Then will ye defile—The overlaying of thy graven images of silver, And the coating of thy molten image, of gold,—Thou wilt cash them away, as a woman the token of her sickness, Begone! shalt thou say thereto,", "darby": "And ye shall defile the silver covering of your graven images, and the gold overlaying of your molten images; thou shalt cast them away as a menstruous cloth: Out! shalt thou say unto it.", "twenty": "", "jps": "And ye shall defile thy graven images overlaid with silver, and thy molten images covered with gold; thou shalt put them far away as one unclean; thou shalt say unto it: 'Get thee hence.'", "acv": "And ye shall defile the overlaying of thy graven images of silver, and the plating of thy molten images of gold. Thou shall cast them away as an unclean thing. Thou shall say to it, Get thee away.", "anderson": "", "haweis": "", "noyes": "Ye shall treat as defiled the silver coverings of your graven images, And the golden clothing of your molten images, Ye shall cast them away as an unclean thing; Away! shall ye say to them.", "webster": "Ye shall defile also the covering of thy graven images of silver, and the ornament of thy molten images of gold: thou shalt cast them away as a polluted cloth; thou shalt say to it, Be gone from me.", "vulgate": "et contaminabis lamminas sculptilium argenti tui et vestimentum conflatilis auri tui et disperges ea sicut inmunditiam menstruatae egredere dices ei;", "brenton": "And thou shalt pollute the plated idols, and thou shalt grind to powder the gilt ones, and shalt scatter them as the water of a removed woman, and thou shalt thrust them forth as dung."}}, {"v": 23, "ref": "30:23", "o": "וְ/נָתַן֩ מְטַ֨ר זַרְעֲ/ךָ֜ אֲשֶׁר תִּזְרַ֣ע אֶת הָ/אֲדָמָ֗ה וְ/לֶ֨חֶם֙ תְּבוּאַ֣ת הָֽ/אֲדָמָ֔ה וְ/הָיָ֥ה דָשֵׁ֖ן וְ/שָׁמֵ֑ן יִרְעֶ֥ה מִקְנֶ֛י/ךָ בַּ/יּ֥וֹם הַ/ה֖וּא כַּ֥ר נִרְחָֽב", "en": {"kjv": "Then shall he give the rain of thy seed, that thou shalt sow the ground withal; and bread of the increase of the earth, and it shall be fat and plenteous: in that day shall thy cattle feed in large pastures.", "web": "He will give the rain for your seed, with which you will sow the ground; and bread of the increase of the ground will be rich and plentiful. In that day, your livestock will feed in large pastures.", "bsb": "Then He will send rain for the seed that you have sown in the ground, and the food that comes from your land will be rich and plentiful. On that day your cattle will graze in open pastures.", "asv": "And he will give the rain for thy seed, wherewith thou shalt sow the ground; and bread of the increase of the ground, and it shall be fat and plenteous. In that day shall thy cattle feed in large pastures;", "ylt": "And He hath given rain for thy seed, With which thou dost sow the ground, And bread, the increase of the ground, And it hath been fat and plenteous, Enjoy do thy cattle in that day an enlarged pasture.", "dra": "And rain shall be given to thy seed, wheresoever thou shalt sow in the land: and the bread of the corn of the land shall be most plentiful, and fat. The lamb in that day shall feed at large in thy possession:", "bbe": "And he will give rain for your seed, so that you may put it in the earth; and you will have bread from the produce of the earth, good and more than enough for your needs: in that day the cattle will get their food in wide grass-lands.", "geneva": "Then shall hee giue raine vnto thy seede, when thou shalt sowe the ground, and bread of the increase of the earth, and it shalbe fat and as oyle: in that day shall thy cattell be fed in large pastures.", "wycliffe": "And reyn schal be youun to thi seed, where euere thou schalt sowe in erthe, and the breed of fruytis of erthe schal be moost plenteuouse and fat; in that dai a lomb schal be fed largeli in thi possessioun.", "rotherham": "Then will he give—Rain for thy seed—wherewith thou shalt sow thy ground and Bread as the increase of thy ground, which shall be fertile and fat,—Thy cattle, in that day, shall feed in broad pasture:", "darby": "And he will give the rain of thy seed with which thou shalt sow the ground; and bread, the produce of the ground, and it shall be fat and rich. In that day shall thy cattle feed in large pastures;", "twenty": "", "jps": "And He will give the rain for thy seed, wherewith thou sowest the ground, and bread of the increase of the ground, and it shall be fat and plenteous; in that day shall thy cattle feed in large pastures.", "acv": "And he will give the rain for thy seed, with which thou shall sow the ground, and bread of the increase of the ground, and it shall be fat and plenteous. In that day thy cattle shall feed in large pastures.", "anderson": "", "haweis": "", "noyes": "Then will he give rain for thy seed, With which thou shalt sow the ground, And the bread-corn, the produce of the land, shall be rich and nourishing; Then shall thy cattle feed in large pastures.", "webster": "Then shall he give the rain of thy seed, with which thou shalt sow the ground; and bread of the increase of the earth, and it shall be fat and plenteous: in that day shall thy cattle feed in large pastures.", "vulgate": "et dabitur pluvia semini tuo ubicumque seminaveris in terra et panis frugum terrae erit uberrimus et pinguis pascetur in possessione tua in die illo agnus spatiose;", "brenton": "Then shall there be rain to the seed of thy land; and the bread of the fruit of thy land shall be plenteous and rich: and thy cattle shall feed in that day in a fertile and spacious place."}}, {"v": 24, "ref": "30:24", "o": "וְ/הָ/אֲלָפִ֣ים וְ/הָ/עֲיָרִ֗ים עֹֽבְדֵי֙ הָֽ/אֲדָמָ֔ה בְּלִ֥יל חָמִ֖יץ יֹאכֵ֑לוּ אֲשֶׁר זֹרֶ֥ה בָ/רַ֖חַת וּ/בַ/מִּזְרֶֽה", "en": {"kjv": "The oxen likewise and the young asses that ear the ground shall eat clean provender, which hath been winnowed with the shovel and with the fan.", "web": "The oxen likewise and the young donkeys that till the ground will eat savory provender, which has been winnowed with the shovel and with the fork.", "bsb": "The oxen and donkeys that work the ground will eat salted fodder, winnowed with shovel and pitchfork.", "asv": "the oxen likewise and the young asses that till the ground shall eat savory provender, which hath been winnowed with the shovel and with the fork.", "ylt": "And the oxen and the young asses serving the ground, Fermented provender do eat, That one is winnowing with shovel and fan.", "dra": "And thy oxen, and the ass colts that till the ground, shall eat mingled provender as it was winnowed in the floor.", "bbe": "And the oxen and the young asses which are used for ploughing, will have salted grain which has been made free from the waste with fork and basket.", "geneva": "The oxen also and the yong asses, that till the ground, shall eate cleane prouender, which is winowed with the shoouel and with the fanne.", "wycliffe": "And thi bolis and coltis of assis, that worchen the lond, schulen ete barli with chaf meynd togidere, as it is wyndewid in the cornfloor.", "rotherham": "And the oxen and the young asses that till the ground, salted provender, shall eat, which hath been winnowed with shovel or fan.", "darby": "and the oxen and the asses that till the ground shall eat salted provender, which hath been winnowed with the shovel and with the fan.", "twenty": "", "jps": "The oxen likewise and the young asses that till the ground shall eat savoury provender, which hath been winnowed with the shovel and with the fan.", "acv": "Likewise the oxen and the young donkeys that till the ground shall eat savory provender, which has been winnowed with the shovel and with the fork.", "anderson": "", "haweis": "", "noyes": "The oxen also, and the young asses, that till the ground, Shall eat well-seasoned provender, Which hath been winnowed with the shovel and the fan.", "webster": "The oxen likewise and the young asses that plow the ground shall eat clean provender, which hath been winnowed with the shovel and with the fan.", "vulgate": "et tauri tui et pulli asinorum qui operantur terram commixtum migma comedent sic in area ut ventilatum est;", "brenton": "Your bulls and your oxen that till the ground, shall eat chaff mixed with winnowed barley."}}, {"v": 25, "ref": "30:25", "o": "וְ/הָיָ֣ה עַל כָּל הַ֣ר גָּבֹ֗הַ וְ/עַל֙ כָּל גִּבְעָ֣ה נִשָּׂאָ֔ה פְּלָגִ֖ים יִבְלֵי מָ֑יִם בְּ/יוֹם֙ הֶ֣רֶג רָ֔ב בִּ/נְפֹ֖ל מִגְדָּלִֽים", "en": {"kjv": "And there shall be upon every high mountain, and upon every high hill, rivers and streams of waters in the day of the great slaughter, when the towers fall.", "web": "There shall be brooks and streams of water on every lofty mountain and on every high hill in the day of the great slaughter, when the towers fall.", "bsb": "And from every high mountain and every raised hill, streams of water will flow in the day of great slaughter, when the towers fall.", "asv": "And there shall be upon every lofty mountain, and upon every high hill, brooks and streams of waters, in the day of the great slaughter, when the towers fall.", "ylt": "And there hath been on every high mount, And on every exalted hill, Rivulets--streams of waters, In a day of much slaughter, in the falling of towers.", "dra": "And there shall be upon every high mountain, and upon every elevated hill rivers of running waters in the day of the slaughter of many, when the tower shall fall.", "bbe": "And there will be rivers and streams of water on every tall mountain and on every high hill, in the day when great numbers are put to the sword, when the towers come down.", "geneva": "And vpon euery hie mountaine, and vpon euery hie hill shall there be riuers and streames of waters, in the day of the great slaughter, when the towers shall fall.", "wycliffe": "And strondis of rennynge watris schulen be on ech hiy munteyn, and on ech litil hil reisid, in the dai of sleyng of many men, whanne touris fallen doun.", "rotherham": "Then shall there be, On every lofty mountain and On every lifted hill, Channels, Conduits of water,—In the great day of slaughter, When the towers fall.", "darby": "And there shall be upon every high mountain and upon every hill that is lifted up, brooks [and] water-courses, in the day of the great slaughter, when the towers fall.", "twenty": "", "jps": "And there shall be upon every lofty mountain, and upon every high hill streams and watercourses, in the day of the great slaughter, when the towers fall.", "acv": "And there shall be upon every lofty mountain, and upon every high hill, brooks and streams of waters, in the day of the great slaughter, when the towers fall.", "anderson": "", "haweis": "", "noyes": "And on every lofty mountain, And on every high hill, Shall be brooks and streams of water, In the day of the great slaughter, When the towers fall.", "webster": "And there shall be upon every high mountain, and upon every high hill, rivers [and] streams of waters in the day of the great slaughter, when the towers fall.", "vulgate": "et erunt super omnem montem excelsum et super omnem collem elevatum rivi currentium aquarum in die interfectionis multorum cum ceciderint turres;", "brenton": "And there shall be upon every lofty mountain and upon every high hill, water running in that day, when many shall perish, and when the towers shall fall."}}, {"v": 26, "ref": "30:26", "o": "וְ/הָיָ֤ה אֽוֹר הַ/לְּבָנָה֙ כְּ/א֣וֹר הַֽ/חַמָּ֔ה וְ/א֤וֹר הַֽ/חַמָּה֙ יִהְיֶ֣ה שִׁבְעָתַ֔יִם כְּ/א֖וֹר שִׁבְעַ֣ת הַ/יָּמִ֑ים בְּ/י֗וֹם חֲבֹ֤שׁ יְהוָה֙ אֶת שֶׁ֣בֶר עַמּ֔/וֹ וּ/מַ֥חַץ מַכָּת֖/וֹ יִרְפָּֽא", "en": {"kjv": "Moreover the light of the moon shall be as the light of the sun, and the light of the sun shall be sevenfold, as the light of seven days, in the day that the Lord bindeth up the breach of his people, and healeth the stroke of their wound.", "web": "Moreover the light of the moon will be like the light of the sun, and the light of the sun will be seven times brighter, like the light of seven days, in the day that Yahweh binds up the fracture of his people, and heals the wound they were struck with.", "bsb": "The light of the moon will be as bright as the sun, and the light of the sun will be seven times brighter—like the light of seven days—on the day that the LORD binds up the brokenness of His people and heals the wounds He has inflicted.", "asv": "Moreover the light of the moon shall be as the light of the sun, and the light of the sun shall be sevenfold, as the light of seven days, in the day that Jehovah bindeth up the hurt of his people, and healeth the stroke of their wound.", "ylt": "And the light of the moon hath been as the light of the sun, And the light of the sun is sevenfold, As the light of seven days, In the day of Jehovah's binding up the breach of His people, When the stroke of its wound He healeth.", "dra": "And the light of the moon shall be as the light of the sun, and the light of the sun shall be sevenfold, as the light of seven days: in the day when the Lord shall bind up the wound of his people, and shall heal the stroke of their wound.", "bbe": "And the light of the moon will be as the light of the sun, and the light of the sun will be seven times greater, as the light of seven days, in the day when the Lord puts oil on the wounds of his people, and makes them well from the blows they have undergone.", "geneva": "Moreouer, the light of the moone shall be as the light of the sunne, and the light of the sunne shalbe seuen folde, and like the light of seuen dayes in the day that the Lord shall binde vp the breach of his people, and heale the stroke of their wound.", "wycliffe": "And the liyt of the moone schal be as the liyt of the sunne, and the liyt of the sunne schal be seuenfold, as the liyt of seuene daies, in the dai in which the Lord schal bynde togidere the wounde of his puple, and schal make hool the smytynge of the wounde therof.", "rotherham": "Then shall the light of the moon, be as the light of the sun, And, the light of the sun, shall be sevenfold, as the light of seven days,—In the day—When Yahweh, bindeth up, the laceration of his people, and When the severe wound caused by smiting them, he healeth.", "darby": "And the light of the moon shall be as the light of the sun, and the light of the sun shall be sevenfold, as the light of seven days, in the day that Jehovah bindeth up the breach of his people, and healeth the wound of their stroke.", "twenty": "", "jps": "Moreover the light of the moon shall be as the light of the sun, and the light of the sun shall be sevenfold, as the light of the seven days, in the day that HaShem bindeth up the bruise of His people, and healeth the stroke of their wound.", "acv": "Moreover the light of the moon shall be as the light of the sun, and the light of the sun shall be sevenfold, as the light of seven days, in the day that Jehovah binds up the hurt of his people, and heals the stroke of their wound.", "anderson": "", "haweis": "", "noyes": "Then shall the light of the moon be as the light of the sun, And the light of the sun shall be sevenfold, [As the light of seven days,] When Jehovah bindeth up the bruises of his people, And healeth the wound which they have received.", "webster": "Moreover the light of the moon shall be as the light of the sun, and the light of the sun shall be seven-fold, as the light of seven days, in the day that the LORD bindeth up the breach of his people, and healeth the stroke of their wound.", "vulgate": "et erit lux lunae sicut lux solis et lux solis erit septempliciter sicut lux septem dierum in die qua alligaverit Dominus vulnus populi sui et percussuram plagae eius sanaverit;", "brenton": "And the light of the moon shall be as the light of the sun, and the light of the sun shall be sevenfold in the day when the Lord shall heal the breach of his people, and shall heal the pain of thy wound."}}, {"v": 27, "ref": "30:27", "o": "הִנֵּ֤ה שֵׁם יְהוָה֙ בָּ֣א מִ/מֶּרְחָ֔ק בֹּעֵ֣ר אַפּ֔/וֹ וְ/כֹ֖בֶד מַשָּׂאָ֑ה שְׂפָתָי/ו֙ מָ֣לְאוּ זַ֔עַם וּ/לְשׁוֹנ֖/וֹ כְּ/אֵ֥שׁ אֹכָֽלֶת", "en": {"kjv": "Behold, the name of the Lord cometh from far, burning with his anger, and the burden thereof is heavy: his lips are full of indignation, and his tongue as a devouring fire:", "web": "Behold, Yahweh’s name comes from far away, burning with his anger, and in thick rising smoke. His lips are full of indignation, and his tongue is as a devouring fire.", "bsb": "Behold, the Name of the LORD comes from afar, with burning anger and dense smoke. His lips are full of fury, and His tongue is like a consuming fire.", "asv": "Behold, the name of Jehovah cometh from far, burning with his anger, and in thick rising smoke: his lips are full of indignation, and his tongue is as a devouring fire;", "ylt": "Lo, the name of Jehovah is coming from far, Burning is His anger, and great the flame, His lips have been full of indignation, And His tongue is as a devouring fire.", "dra": "Behold the name of the Lord cometh from afar, his wrath burneth, and is heavy to bear: his lips are filled with indignation, and his tongue as a devouring fire.", "bbe": "See, the name of the Lord is coming from far, burning with his wrath, with thick smoke going up: his lips are full of passion, and his tongue is like a burning fire:", "geneva": "Beholde, the Name of the Lord commeth from farre, his face is burning, and the burden thereof is heauy: his lips are full of indignation, and his tongue is as a deuouring fire.", "wycliffe": "Lo! the name of the Lord cometh doun fro fer; his strong veniaunce is brennynge and greuouse to bere; hise lippis ben fillid of indignacioun, and his tunge is as fier deuouringe.", "rotherham": "Lo! the Name of Yahweh, coming in from afar, His anger kindling, A heavy storm,—His lips, are full of indignation, And, his tongue, is like a fire that devoureth;", "darby": "Behold, the name of Jehovah cometh from far, burning [with] his anger — a grievous conflagration; his lips are full of indignation, and his tongue as a consuming fire;", "twenty": "", "jps": "Behold, the name of HaShem cometh from far, with His anger burning, and in thick uplifting of smoke; His lips are full of indignation, and His tongue is as a devouring fire;", "acv": "Behold, the name of Jehovah comes from far, burning with his anger, and in thick rising smoke. His lips are full of indignation, and his tongue is as a devouring fire,", "anderson": "", "haweis": "", "noyes": "Behold, the name of Jehovah cometh from afar, His anger burneth, and violent is the flame, His lips are full of indignation, And his tongue like a devouring fire.", "webster": "Behold, the name of the LORD cometh from far, burning [with] his anger, and the burden [of it is] heavy: his lips are full of indignation, and his tongue as a devouring fire:", "vulgate": "ecce nomen Domini venit de longinquo ardens furor eius et gravis ad portandum labia eius repleta sunt indignatione et lingua eius quasi ignis devorans;", "brenton": "Behold, the name of the Lord comes after a long time, burning wrath: the word of his lips is with glory, a word full of anger, and the anger of his wrath shall devour as fire."}}, {"v": 28, "ref": "30:28", "o": "וְ/רוּח֞/וֹ כְּ/נַ֤חַל שׁוֹטֵף֙ עַד צַוָּ֣אר יֶֽחֱצֶ֔ה לַ/הֲנָפָ֥ה גוֹיִ֖ם בְּ/נָ֣פַת שָׁ֑וְא וְ/רֶ֣סֶן מַתְעֶ֔ה עַ֖ל לְחָיֵ֥י עַמִּֽים", "en": {"kjv": "And his breath, as an overflowing stream, shall reach to the midst of the neck, to sift the nations with the sieve of vanity: and there shall be a bridle in the jaws of the people, causing them to err.", "web": "His breath is as an overflowing stream that reaches even to the neck, to sift the nations with the sieve of destruction; and a bridle that leads to ruin will be in the jaws of the peoples.", "bsb": "His breath is like a rushing torrent that rises to the neck. He comes to sift the nations in a sieve of destruction; He bridles the jaws of the peoples to lead them astray.", "asv": "and his breath is as an overflowing stream, that reacheth even unto the neck, to sift the nations with the sieve of destruction: and a bridle that causeth to err shall be in the jaws of the peoples.", "ylt": "And His breath is as an overflowing stream, Unto the neck it divideth, To sift nations with a sieve of vanity, And a bridle causing to err, Is on the jaws of the peoples.", "dra": "His breath as a torrent overflowing even to the midst of the neck, to destroy the nations unto nothing, and the bridle of error that was in the jaws of the people.", "bbe": "And his breath is as an overflowing stream, coming up even to the neck, shaking the nations for their destruction, like the shaking of grain in a basket: and he will put a cord in the mouths of the people, turning them out of their way.", "geneva": "And his spirit is as a riuer that ouerfloweth vp to the necke: it deuideth asunder, to fanne the nations with the fanne of vanitie, and there shall be a bridle to cause them to erre in the chawes of the people.", "wycliffe": "His spirit is as a stef streem, flowynge `til to the myddis of the necke, to leese folkis in to nouyt, and the bridil of errour, that was in the chekis of puplis.", "rotherham": "And, his breath like an overflowing torrent, even unto the neck, doth reach, To sift nations with a sieve of calamity,—A bridle leading to ruin, being upon the jaws of the peoples.", "darby": "and his breath as an overflowing torrent, which reacheth even to the neck, to sift the nations with the sieve of destruction, and [to put] a bridle into the jaws of the peoples, that causeth them to go astray.", "twenty": "", "jps": "And His breath is as an overflowing stream, that divideth even unto the neck, to sift the nations with the sieve of destruction; and a bridle that causeth to err shall be in the jaws of the peoples.", "acv": "and his breath is as an overflowing stream that reaches even to the neck, to sift the nations with the sieve of destruction. And a bridle that causes to err shall be in the jaws of the peoples.", "anderson": "", "haweis": "", "noyes": "His breath is like an overflowing torrent, That reacheth even to the neck; He will toss the nation with the winnowing-fan of destruction; He will put a bridle upon the jaws of the people, that shall lead them astray.", "webster": "And his breath, as an overflowing stream, shall reach to the midst of the neck, to sift the nations with the sieve of vanity: and [there shall be] a bridle in the jaws of the people, causing [them] to err.", "vulgate": "spiritus eius velut torrens inundans usque ad medium colli ad perdendas gentes in nihilum et frenum erroris quod erat in maxillis populorum;", "brenton": "And his breath, as rushing water in a valley, shall reach as far as the neck, and be divided, to confound the nations for their vain error: error also shall pursue them, and overtake them."}}, {"v": 29, "ref": "30:29", "o": "הַ/שִּׁיר֙ יִֽהְיֶ֣ה לָ/כֶ֔ם כְּ/לֵ֖יל הִתְקַדֶּשׁ חָ֑ג וְ/שִׂמְחַ֣ת לֵבָ֗ב כַּֽ/הוֹלֵךְ֙ בֶּֽ/חָלִ֔יל לָ/ב֥וֹא בְ/הַר יְהוָ֖ה אֶל צ֥וּר יִשְׂרָאֵֽל", "en": {"kjv": "Ye shall have a song, as in the night when a holy solemnity is kept; and gladness of heart, as when one goeth with a pipe to come into the mountain of the Lord, to the mighty One of Israel.", "web": "You will have a song, as in the night when a holy feast is kept; and gladness of heart, as when one goes with a flute to come to Yahweh’s mountain, to Israel’s Rock.", "bsb": "You will sing as on the night of a holy festival, and your heart will rejoice like one who walks to the music of a flute, going up to the mountain of the LORD, to the Rock of Israel.", "asv": "Ye shall have a song as in the night when a holy feast is kept; and gladness of heart, as when one goeth with a pipe to come unto the mountain of Jehovah, to the Rock of Israel.", "ylt": "Singing is to you as in a night sanctified for a festival, And joy of heart as he who is going with a pipe, To go in to the mountain of Jehovah, Unto the rock of Israel.", "dra": "You shall have a song as in the night of the sanctified solemnity, and joy of heart, as where one goeth with a pipe, to come into the mountain of the Lord, to the Mighty One of Israel.", "bbe": "You will have a song, as in the night when a holy feast is kept; and you will be glad in heart, as when they go with music of the pipe to the mountain of the Lord, the Rock of Israel.", "geneva": "But there shall be a song vnto you as in the night, when solemne feast is kept: and gladnes of heart, as he that commeth with a pipe to goe vnto the mount of the Lord, to the mightie one of Israel.", "wycliffe": "Song schal be to you, as the vois of an halewid solempnyte; and gladnesse of herte, as he that goth with a pipe, for to entre in to the hil of the Lord, to the stronge of Israel.", "rotherham": "A song, shall ye have, As in the night of hallowing a festival,—And gladness of heart, As when one goeth with the flute to enter Into the mountain of Yahweh Unto the Rock of Israel.", "darby": "Ye shall have a song, as in the night when a feast is sanctified; and joy of heart, as of one who goeth with a pipe to come unto the mountain of Jehovah, to the Rock of Israel.", "twenty": "", "jps": "Ye shall have a song as in the night when a feast is hallowed; and gladness of heart, as when one goeth with the pipe to come into the mountain of HaShem, to the Rock of Israel.", "acv": "Ye shall have a song as in the night when a holy feast is kept, and gladness of heart, as he who goes with a pipe to come to the mountain of Jehovah, to the Rock of Israel.", "anderson": "", "haweis": "", "noyes": "But ye shall then sing as in the night of a solemn festival; Your heart shall be glad, like his who marcheth with the sound of the pipe To the mountain of Jehovah, to the rock of Israel.", "webster": "Ye shall have a song, as in the night, [when] a holy solemnity is kept; and gladness of heart, as when one goeth with a pipe to come upon the mountain of the LORD, to the mighty One of Israel.", "vulgate": "canticum erit vobis sicut nox sanctificatae sollemnitatis et laetitia cordis sicut qui pergit cum tibia ut intret in montem Domini ad Fortem Israhel;", "brenton": "Must ye always rejoice, and go into my holy places continually, as they that keep a feast? and must ye go with a pipe, as those that rejoice, into the mountain of the Lord, to the God of Israel?"}}, {"v": 30, "ref": "30:30", "o": "וְ/הִשְׁמִ֨יעַ יְהוָ֜ה אֶת ה֣וֹד קוֹל֗/וֹ וְ/נַ֤חַת זְרוֹע/וֹ֙ יַרְאֶ֔ה בְּ/זַ֣עַף אַ֔ף וְ/לַ֖הַב אֵ֣שׁ אוֹכֵלָ֑ה נֶ֥פֶץ וָ/זֶ֖רֶם וְ/אֶ֥בֶן בָּרָֽד", "en": {"kjv": "And the Lord shall cause his glorious voice to be heard, and shall shew the lighting down of his arm, with the indignation of his anger, and with the flame of a devouring fire, with scattering, and tempest, and hailstones.", "web": "Yahweh will cause his glorious voice to be heard, and will show the descent of his arm, with the indignation of his anger, and the flame of a devouring fire, with a blast, storm, and hailstones.", "bsb": "And the LORD will cause His majestic voice to be heard and His mighty arm to be revealed, striking in angry wrath with a flame of consuming fire, and with cloudburst, storm, and hailstones.", "asv": "And Jehovah will cause his glorious voice to be heard, and will show the lighting down of his arm, with the indignation of his anger, and the flame of a devouring fire, with a blast, and tempest, and hailstones.", "ylt": "And caused to be heard hath Jehovah The honour of His voice, And the coming down of His arm He doth shew with the raging of anger, And the flame of a consuming fire, Scattering, and inundation, and hailstone.", "dra": "And the Lord shall make the glory of his voice to be heard, and shall shew the terror of his arm, in the threatening of wrath, and the flame of devouring fire: he shall crush to pieces with whirlwind, and hailstones.", "bbe": "And the Lord will send out the sound of his great voice, and they will see his arm stretched out, with the heat of his wrath, and the flame of a burning fire; with a cloud-burst, and storm, and a rain of ice.", "geneva": "And the Lord shall cause his glorious voyce to be heard, and shall declare the lighting downe of his arme with the anger of his countenance, and flame of a deuouring fire, with scattering and tempest, and hailestones.", "wycliffe": "And the Lord schal make herd the glorie of his vois, and he schal schewe the ferdfulnesse of his arm in manassyng of strong veniaunce, and in flawme of fier brennynge; he schal hurtle doun in whirlewynd, and in stoon of hail.", "rotherham": "Then will Yahweh cause to be heard—the resounding of his voice And the bringing down of his arm, shall be seen, In a rage of anger, And with the flame of a devouring fire,—A burst and a downpour, and a hailstone!", "darby": "And Jehovah will cause the majesty of his voice to be heard, and will shew the lighting down of his arm with indignation of anger, and a flame of consuming fire, with waterflood and storm and hailstones.", "twenty": "", "jps": "And HaShem will cause His glorious voice to be heard, and will show the lighting down of His arm, with furious anger, and the flame of a devouring fire, with a bursting of clouds, and a storm of rain, and hailstones.", "acv": "And Jehovah will cause his glorious voice to be heard, and will show the coming down of his arm with the indignation of his anger, and the flame of a devouring fire, with a blast and tempest and hailstones.", "anderson": "", "haweis": "", "noyes": "Jehovah will cause his glorious voice to be heard, And the blow of his arm to be seen, With furious anger, and flames of devouring fire; With flood, and storm, and hailstones.", "webster": "And the LORD shall cause his glorious voice to be heard, and shall show the lighting down of his arm, with the indignation of [his] anger, and [with] the flame of a devouring fire, [with] scattering, and tempest, and hailstones.", "vulgate": "et auditam faciet Dominus gloriam vocis suae et terrorem brachii sui ostendet in comminatione furoris et flamma ignis devorantis adlidet in turbine et in lapide grandinis;", "brenton": "And the Lord shall make his glorious voice to be heard, and the wrath of his arm, to make a display with wrath and anger and devouring flame: he shall lighten terribly, and his wrath shall be as water and violent hail."}}, {"v": 31, "ref": "30:31", "o": "כִּֽי מִ/קּ֥וֹל יְהוָ֖ה יֵחַ֣ת אַשּׁ֑וּר בַּ/שֵּׁ֖בֶט יַכֶּֽה", "en": {"kjv": "For through the voice of the Lord shall the Assyrian be beaten down, which smote with a rod.", "web": "For through the voice of Yahweh the Assyrian will be dismayed. He will strike him with his rod.", "bsb": "For Assyria will be shattered at the voice of the LORD; He will strike them with His scepter.", "asv": "For through the voice of Jehovah shall the Assyrian be dismayed; with his rod will he smite him.", "ylt": "For from the voice of Jehovah broken down is Asshur, With a rod He smiteth.", "dra": "For at the voice of the Lord the Assyrian shall fear being struck with the rod.", "bbe": "For through the voice of the Lord the Assyrian will be broken, and the Lord's rod will be lifted up against him.", "geneva": "For with the voyce of the Lord shall Asshur be destroyed, which smote with the rod.", "wycliffe": "For whi Assur smytun with a yerde schal drede of the vois of the Lord;", "rotherham": "For at the voice of Yahweh, shall Assyria be crushed,—With his rod, will he smite.", "darby": "For through the voice of Jehovah shall the Assyrian be broken down: he will smite [him] with the rod.", "twenty": "", "jps": "For through the voice of HaShem shall Asshur be dismayed, the rod with which He smote.", "acv": "For through the voice of Jehovah the Assyrian shall be dismayed. With his rod he will smite him.", "anderson": "", "haweis": "", "noyes": "For by the voice of Jehovah shall the Assyrian be beaten down; He will smite him with the rod.", "webster": "For through the voice of the LORD shall the Assyrian be beaten down, [who] smote with a rod.", "vulgate": "a voce enim Domini pavebit Assur virga percussus;", "brenton": "For by the voice of the Lord the Assyrians shall be overcome, even by the stroke wherewith he shall smite them."}}, {"v": 32, "ref": "30:32", "o": "וְ/הָיָ֗ה כֹּ֤ל מַֽעֲבַר֙ מַטֵּ֣ה מֽוּסָדָ֔ה אֲשֶׁ֨ר יָנִ֤יחַ יְהוָה֙ עָלָ֔י/ו בְּ/תֻפִּ֖ים וּ/בְ/כִנֹּר֑וֹת וּ/בְ/מִלְחֲמ֥וֹת תְּנוּפָ֖ה נִלְחַם ב/ה בָּֽ/ם", "en": {"kjv": "And in every place where the grounded staff shall pass, which the Lord shall lay upon him, it shall be with tabrets and harps: and in battles of shaking will he fight with it.", "web": "Every stroke of the rod of punishment, which Yahweh will lay on him, will be with the sound of tambourines and harps. He will fight with them in battles, brandishing weapons.", "bsb": "And with every stroke of the rod of punishment that the LORD brings down on them, the tambourines and lyres will sound as He battles with weapons brandished.", "asv": "And every stroke of the appointed staff, which Jehovah shall lay upon him, shall be with the sound of tabrets and harps; and in battles with the brandishing of his arm will he fight with them.", "ylt": "And every passage of the settled staff, That Jehovah causeth to rest on him, Hath been with tabrets, and with harps, And in battles of shaking he hath fought with it.", "dra": "And the passage of the rod shall be strongly grounded, which the Lord shall make to rest upon him with timbrels and harps, and in great battles he shall overthrow them.", "bbe": "And every blow of the rod of his punishment, which the Lord will send on him, will be with the sound of music: and with the waving of his sword the Lord will make war against him.", "geneva": "And in euery place that ye staffe shall passe, it shall cleaue fast, which the Lord shall lay vpon him with tabrets and harpes: and with battels, and lifting vp of hands shall he fight against it.", "wycliffe": "and the passyng of the yerd schal be foundid, which yerde the Lord schal make for to reste on hym. In tympans, and harpis, and in souereyn batels he schal ouercome hem.", "rotherham": "And it shall come to pass,—that, every stroke of the staff of doom which Yahweh shall lay upon him, shall be with timbrels and with lyres,—when, with battles of brandished weapons, he hath fought against them.", "darby": "And wherever shall pass the appointed staff, which Jehovah shall lay upon him, it shall be with tambours and harps; and with tumultuous battles will he fight with it.", "twenty": "", "jps": "And in every place where the appointed staff shall pass, which HaShem shall lay upon him, it shall be with tabrets and harps; and in battles of wielding will He fight with them.", "acv": "And every stroke of the appointed staff, which Jehovah shall lay upon him, shall be with the sound of tambourine and harps. And he will fight with them in battles with the brandishing of his arm.", "anderson": "", "haweis": "", "noyes": "And as often as the appointed rod shall strike, Which Jehovah shall lay heavily upon him, It shall be accompanied with tabrets and harps; And with fierce battles will he fight against him.", "webster": "And [in] every place where the grounded staff shall pass, which the LORD shall lay upon him, [it] shall be with tabrets and harps: and in battles of shaking will he fight with it.", "vulgate": "et erit transitus virgae fundatus quam requiescere faciet Dominus super eum in tympanis et in citharis et in bellis praecipuis expugnabit eos;", "brenton": "And it shall happen to him from every side, that they from whom their hope of assistance was, in which he trusted, themselves shall war against him in turn with drums and with harp."}}, {"v": 33, "ref": "30:33", "o": "כִּֽי עָר֤וּךְ מֵֽ/אֶתְמוּל֙ תָּפְתֶּ֔ה גַּם הוא הִ֛יא לַ/מֶּ֥לֶךְ הוּכָ֖ן הֶעְמִ֣יק הִרְחִ֑ב מְדֻרָתָ֗/הּ אֵ֤שׁ וְ/עֵצִים֙ הַרְבֵּ֔ה נִשְׁמַ֤ת יְהוָה֙ כְּ/נַ֣חַל גָּפְרִ֔ית בֹּעֲרָ֖ה בָּֽ/הּ", "en": {"kjv": "For Tophet is ordained of old; yea, for the king it is prepared; he hath made it deep and large: the pile thereof is fire and much wood; the breath of the Lord, like a stream of brimstone, doth kindle it.", "web": "For his burning place has long been ready. Yes, for the king it is prepared. He has made its pyre deep and large with fire and much wood. Yahweh’s breath, like a stream of sulfur, kindles it.", "bsb": "For Topheth has long been prepared; it has been made ready for the king. Its funeral pyre is deep and wide, with plenty of fire and wood. The breath of the LORD, like a torrent of burning sulfur, sets it ablaze.", "asv": "For a Topheth is prepared of old; yea, for the king it is made ready; he hath made it deep and large; the pile thereof is fire and much wood; the breath of Jehovah, like a stream of brimstone, doth kindle it.", "ylt": "For, arranged from former time is Tophet, Even it for the king is prepared, He hath made deep, He hath made large, Its pile is fire and much wood, The breath of Jehovah, As a stream of brim stone, is burning in it!", "dra": "For Topheth is prepared from yesterday, prepared by the king, deep, and wide. The nourishment thereof is fire and much wood: the breath of the Lord as a torrent of brimstone kindling it.", "bbe": "For a place of fire has long been ready; yes, it has been made ready for the king; he has made it deep and wide: it is massed with fire and much wood; the breath of the Lord, like a stream of fire, puts a light to it.", "geneva": "For Tophet is prepared of olde: it is euen prepared for the King: hee hath made it deepe and large: the burning thereof is fire and much wood: the breath of the Lord, like a riuer of brimstone, doeth kindle it.", "wycliffe": "For whi Tophet, that is, helle, deep and alargid, is maad redi of the kyng fro yistirdai; the nurschyngis therof ben fier and many trees; the blast of the Lord as a streem of brymstoon kyndlith it.", "rotherham": "For there hath been set in order, beforehand a Topheth, Yea, the same, for the king, hath been prepared He hath made it deep—made it large,—The circumference thereof is for fire and wood in abundance, the breath of Yahweh, like a torrent of brimstone, is ready to kindle it.", "darby": "For Topheth is prepared of old; for the king also it is prepared: he hath made it deep and large; its pile is fire and much wood; the breath of Jehovah, like a stream of brimstone, doth kindle it.", "twenty": "", "jps": "For a hearth is ordered of old; yea, for the king it is prepared, deep and large; the pile thereof is fire and much wood; the breath of HaShem, like a stream of brimstone, doth kindle it.", "acv": "For a Topheth is prepared of old, yea, it is made ready for the king. He has made it deep and large. The pile of it is fire and much wood. The breath of Jehovah kindles it, like a stream of brimstone.", "anderson": "", "haweis": "", "noyes": "For long hath the burning place been prepared; Yea, for the king hath it been made ready; The pile is made deep and broad; There is fire and wood in abundance; The breath of Jehovah, like a stream of brimstone, kindle it.", "webster": "For Tophet [is] ordained of old; yes, for the king it is prepared; he hath made [it] deep [and] large: the pile of it [is] fire and much wood; the breath of the LORD, like a stream of brimstone, doth kindle it.", "vulgate": "praeparata est enim ab heri Thofeth a rege praeparata profunda et dilatata nutrimenta eius ignis et ligna multa flatus Domini sicut torrens sulphuris succendens eam;", "brenton": "For thou shalt be required before thy time: has it been prepared for thee also to reign? nay, God has prepared for thee a deep trench, wood piled, fire and much wood: the wrath of the Lord shall be as a trench kindled with sulphur."}}]}, {"c": 31, "verses": [{"v": 1, "ref": "31:1", "o": "ה֣וֹי הַ/יֹּרְדִ֤ים מִצְרַ֨יִם֙ לְ/עֶזְרָ֔ה עַל סוּסִ֖ים יִשָּׁעֵ֑נוּ וַ/יִּבְטְח֨וּ עַל רֶ֜כֶב כִּ֣י רָ֗ב וְ/עַ֤ל פָּֽרָשִׁים֙ כִּֽי עָצְמ֣וּ מְאֹ֔ד וְ/לֹ֤א שָׁעוּ֙ עַל קְד֣וֹשׁ יִשְׂרָאֵ֔ל וְ/אֶת יְהוָ֖ה לֹ֥א דָרָֽשׁוּ", "en": {"kjv": "Woe to them that go down to Egypt for help; and stay on horses, and trust in chariots, because they are many; and in horsemen, because they are very strong; but they look not unto the Holy One of Israel, neither seek the Lord!", "web": "Woe to those who go down to Egypt for help, and rely on horses, and trust in chariots because they are many, and in horsemen because they are very strong, but they don’t look to the Holy One of Israel, and they don’t seek Yahweh!", "bsb": "Woe to those who go down to Egypt for help, who rely on horses, who trust in their abundance of chariots and in their multitude of horsemen. They do not look to the Holy One of Israel; they do not seek the LORD.", "asv": "Woe to them that go down to Egypt for help, and rely on horses, and trust in chariots because they are many, and in horsemen because they are very strong, but they look not unto the Holy One of Israel, neither seek Jehovah!", "ylt": "Woe to those going down to Egypt for help, And on horses lean, And trust on chariots, because many, And on horsemen, because very strong, And have not looked on the Holy One of Israel, And Jehovah have not sought.", "dra": "Woe to them that go down to Egypt for help, trusting in horses, and putting their confidence in chariots, because they are many: and in horsemen, because they are very strong: and have not trusted in the Holy One of Israel, and have not sought after the Lord.", "bbe": "Cursed are those who go down to Egypt for help, and who put their faith in horses; looking to war-carriages for salvation, because of their numbers; and to horsemen, because they are very strong; but they are not looking to the Holy One of Israel, or turning their hearts to the Lord;", "geneva": "Woe vnto them that goe downe into Egypt for helpe, and stay vpon horses, and trust in charets, because they are many, and in horsemen, because they be very strong: but they looke not vnto the holy one of Israel, nor seeke vnto the Lord.", "wycliffe": "Wo to hem that goon doun in to Egipt to help, and hopen in horsis, and han trist on cartis, for tho ben manye, and on knyytis, for thei ben ful stronge; and thei tristiden not on the hooli of Israel, and thei souyten not the Lord.", "rotherham": "Alas! for them who are going down to Egypt for help, On horses, would rely,—And have trusted—In chariots—because they are many, and In horsemen, because they are very bold, But have not looked unto the Holy One of Israel, And onto Yahweh, have not sought.", "darby": "Woe to them that go down to Egypt for help, and depend on horses, and confide in chariots because [they are] many, and in horsemen because they are very strong; and who look not unto the Holy One of Israel, neither seek Jehovah!", "twenty": "", "jps": "Woe to them that go down to Egypt for help, and rely on horses, and trust in chariots, because they are many, and in horsemen, because they are exceeding mighty; but they look not unto the Holy One of Israel, neither seek HaShem!", "acv": "Woe to those who go down to Egypt for help, and rely on horses, and trust in chariots because they are many, and in horsemen because they are very strong, but they look not to the Holy One of Israel, nor seek Jehovah!", "anderson": "", "haweis": "", "noyes": "Woe to them that go down to Egypt for help, And put their trust in horses, And confide in chariots, because they are many, And in horsemen, because their number is great, But look not to the Holy One of Israel, And resort not to Jehovah.", "webster": "Woe to them that go down to Egypt for help; and rely on horses, and trust in chariots, because [they are] many; and in horsemen, because they are very strong; but they look not to the Holy One of Israel, neither seek the LORD!", "vulgate": "vae qui descendunt in Aegyptum ad auxilium in equis sperantes et habentes fiduciam super quadrigis quia multae sunt et super equitibus quia praevalidi nimis et non sunt confisi super Sanctum Israhel et Dominum non requisierunt;", "brenton": "Woe to them that go down to Egypt for help, who trust in horses and chariots, for they are many; and in horses, which are a great multitude; and have not trusted in the Holy One of Israel, and have not sought the Lord."}}, {"v": 2, "ref": "31:2", "o": "וְ/גַם ה֤וּא חָכָם֙ וַ/יָּ֣בֵא רָ֔ע וְ/אֶת דְּבָרָ֖י/ו לֹ֣א הֵסִ֑יר וְ/קָם֙ עַל בֵּ֣ית מְרֵעִ֔ים וְ/עַל עֶזְרַ֖ת פֹּ֥עֲלֵי אָֽוֶן", "en": {"kjv": "Yet he also is wise, and will bring evil, and will not call back his words: but will arise against the house of the evildoers, and against the help of them that work iniquity.", "web": "Yet he also is wise, and will bring disaster, and will not call back his words, but will arise against the house of the evildoers, and against the help of those who work iniquity.", "bsb": "Yet He too is wise and brings disaster; He does not call back His words. He will rise up against the house of the wicked and against the allies of evildoers.", "asv": "Yet he also is wise, and will bring evil, and will not call back his words, but will arise against the house of the evil-doers, and against the help of them that work iniquity.", "ylt": "And He also is wise, and bringeth in evil, And His words He hath not turned aside, And He hath risen against a house of evil doers, And against the help of workers of iniquity.", "dra": "But he that is the wise one hath brought evil, and hath not removed his words: and he will rise up against the house of the wicked, and against the aid of them that work iniquity.", "bbe": "Though he is wise, and able to send evil, and his purpose will not be changed; but he will go against the house of the evil-doers, and against those to whom they are looking for help.", "geneva": "But he yet is wisest: therefore he wil bring euill, and not turne backe his worde, but he will arise against the house of the wicked, and against the helpe of them that worke vanitie.", "wycliffe": "Forsothe he that is wijs, hath brouyt yuel, and took not awei hise wordis; and he schal rise togidere ayens the hous of worste men, and ayens the helpe of hem that worchen wickidnesse.", "rotherham": "But, he also, is wise, and hath brought in calamity, And his own words, hath he not set aside,—Therefore will he rise up, Against the house of evil-doers, and Against the help of the workers of iniquity.", "darby": "But he also is wise, and he bringeth evil, and recalleth not his words; and he will arise against the house of evildoers, and against the help of workers of iniquity.", "twenty": "", "jps": "Yet He also is wise, and bringeth evil, and doth not call back His words; but will arise against the house of the evil-doers, and against the help of them that work iniquity.", "acv": "Yet he also is wise, and will bring evil, and will not call back his words, but will arise against the house of the evildoers, and against the help of those who work iniquity.", "anderson": "", "haweis": "", "noyes": "Yet he, too, is wise; He will bring evil, and not take back his words; He will arise against the house of the evil-doers, And against the help of them that do iniquity.", "webster": "Yet he also [is] wise, and will bring evil, and will not call back his words: but will arise against the house of the evil-doers, and against the help of them that work iniquity.", "vulgate": "ipse autem sapiens adduxit malum et verba sua non abstulit et consurget contra domum pessimorum et contra auxilium operantium iniquitatem;", "brenton": "Therefore he has wisely brought evils upon them, and his word shall not be frustrated; and he shall rise up against the houses of wicked men, and against their vain hope,"}}, {"v": 3, "ref": "31:3", "o": "וּ/מִצְרַ֤יִם אָדָם֙ וְֽ/לֹא אֵ֔ל וְ/סוּסֵי/הֶ֥ם בָּשָׂ֖ר וְ/לֹא ר֑וּחַ וַֽ/יהוָ֞ה יַטֶּ֣ה יָד֗/וֹ וְ/כָשַׁ֤ל עוֹזֵר֙ וְ/נָפַ֣ל עָזֻ֔ר וְ/יַחְדָּ֖ו כֻּלָּ֥/ם יִכְלָיֽוּ/ן", "en": {"kjv": "Now the Egyptians are men, and not God; and their horses flesh, and not spirit. When the Lord shall stretch out his hand, both he that helpeth shall fall, and he that is holpen shall fall down, and they all shall fail together.", "web": "Now the Egyptians are men, and not God; and their horses flesh, and not spirit. When Yahweh stretches out his hand, both he who helps shall stumble, and he who is helped shall fall, and they all shall be consumed together.", "bsb": "But the Egyptians are men, not God; their horses are flesh, not spirit. When the LORD stretches out His hand, the helper will stumble, and the one he helps will fall; both will perish together.", "asv": "Now the Egyptians are men, and not God; and their horses flesh, and not spirit: and when Jehovah shall stretch out his hand, both he that helpeth shall stumble, and he that is helped shall fall, and they all shall be consumed together.", "ylt": "And the Egyptians are men , and not God, And their horses are flesh, and not spirit, And Jehovah stretcheth out His hand, And stumbled hath the helper, And fallen hath the helped one, And together all of them are consumed.", "dra": "Egypt is man, and not God: and their horses, flesh, and not spirit: and the Lord shall put down his hand, and the helper shall fall, and he that is helped shall fall, and they shall all be confounded together.", "bbe": "For the Egyptians are men, and not God; and their horses are flesh, and not spirit: and when the Lord's hand is stretched out, the helper and he who is helped will come down together.", "geneva": "Now the Egyptians are men, and not God, and their horses flesh and not spirite: and when the Lord shall stretch out his hand, the helper shall fall, and hee that is holpen shall fall, and they shall altogether faile.", "wycliffe": "Egipt is a man, and not God; and the horsis of hem ben fleisch, and not spirit; and the Lord schal bowe doun his hond, and the helpere schal falle doun, and he schal falle, to whom help is youun, and alle schulen be wastid togidere.", "rotherham": "Now, the Egyptians, are, men, and not, GOD, And, their horses, flesh, and not, spirit; When, Yahweh, shall stretch out his hand, Then, he that is giving help, shall stumble And, he that is receiving help, shall fall, And, together, shall, all of them, vanish!", "darby": "And the Egyptians are men, and notGod, and their horses flesh, and not spirit; and Jehovah shall stretch forth his hand, and he that helpeth shall stumble, and he that is helped shall fall, and they all shall perish together.", "twenty": "", "jps": "Now the Egyptians are men, and not G-d, and their horses flesh, and not spirit; so when HaShem shall stretch out His hand, both he that helpeth shall stumble, and he that is helped shall fall, and they all shall perish together.", "acv": "Now the Egyptians are men, and not God, and their horses flesh, and not spirit. And when Jehovah shall stretch out his hand, both he who helps shall stumble, and he who is helped shall fall, and they shall all be consumed together.", "anderson": "", "haweis": "", "noyes": "The Egyptians are men, and not God, And their horses are flesh, and not spirit. When Jehovah shall stretch forth his hand, Then shall the helper fall, and the helped be overthrown; And they shall all perish together.", "webster": "Now the Egyptians [are] men, and not God; and their horses flesh, and not spirit. When the LORD shall stretch out his hand, both he that helpeth shall fall, and he that is helped shall fall down, and they all shall fail together.", "vulgate": "Aegyptus homo et non deus et equi eorum caro et non spiritus et Dominus inclinabit manum suam et corruet auxiliator et cadet cui praestatur auxilium simulque omnes consumentur;", "brenton": "even an Egyptian, a man, and not God; the flesh of horses, and there is no help in them: but the Lord shall bring his hand upon them, and the helpers shall fail, and all shall perish together."}}, {"v": 4, "ref": "31:4", "o": "כִּ֣י כֹ֣ה אָֽמַר יְהוָ֣ה אֵלַ֡/י כַּ/אֲשֶׁ֣ר יֶהְגֶּה֩ הָ/אַרְיֵ֨ה וְ/הַ/כְּפִ֜יר עַל טַרְפּ֗/וֹ אֲשֶׁ֨ר יִקָּרֵ֤א עָלָי/ו֙ מְלֹ֣א רֹעִ֔ים מִ/קּוֹלָ/ם֙ לֹ֣א יֵחָ֔ת וּ/מֵֽ/הֲמוֹנָ֖/ם לֹ֣א יַֽעֲנֶ֑ה כֵּ֗ן יֵרֵד֙ יְהוָ֣ה צְבָא֔וֹת לִ/צְבֹּ֥א עַל הַר צִיּ֖וֹן וְ/עַל גִּבְעָתָֽ/הּ", "en": {"kjv": "For thus hath the Lord spoken unto me, Like as the lion and the young lion roaring on his prey, when a multitude of shepherds is called forth against him, he will not be afraid of their voice, nor abase himself for the noise of them: so shall the Lord of hosts come down to fight for mount Zion, and for the hill thereof.", "web": "For thus says Yahweh to me, “As the lion and the young lion growling over his prey, if a multitude of shepherds is called together against him, will not be dismayed at their voice, nor abase himself for their noise, so Yahweh of Armies will come down to fight on Mount Zion and on its heights.", "bsb": "For this is what the LORD has said to me: “Like a lion roaring or a young lion over its prey— and though a band of shepherds is called out against it, it is not terrified by their shouting or subdued by their clamor— so the LORD of Hosts will come down to do battle on Mount Zion and its heights.", "asv": "For thus saith Jehovah unto me, As the lion and the young lion growling over his prey, if a multitude of shepherds be called forth against him, will not be dismayed at their voice, nor abase himself for the noise of them: so will Jehovah of hosts come down to fight upon mount Zion, and upon the hill thereof.", "ylt": "For thus said Jehovah unto me: `As growl doth the lion and the young lion over his prey, Called against whom is a multitude of shepherds, From their voice he is not affrighted, And from their noise he is not humbled; So come down doth Jehovah of Hosts To war on mount Zion, and on her height.", "dra": "For thus saith the Lord to me: Like as the lion roareth, and the lions whelp upon his prey, and when a multitude of shepherds shall come against him, he will not fear at their voice, nor be afraid of their multitude: so shall the Lord of hosts come down to fight upon mount Sion, and upon the hill thereof.", "bbe": "For the Lord has said to me, As a lion, or a young lion, makes an angry noise over his food, and if a band of herdsmen come out against him, he will not be in fear of their voices, or give up his food for their noise: so the Lord of armies will come down to make war against Mount Zion and its hill.", "geneva": "For thus hath the Lord spoken vnto me, As the lyon or lyons whelpe roareth vpon his praye, against whom if a multitude of shepheards be called, hee will not be afraide at their voyce, neither will humble him selfe at their noise: so shall the Lord of hostes come downe to fight for mount Zion, and for the hill thereof.", "wycliffe": "For whi the Lord seith these thingis to me, If a lioun rorith, and a whelp of a lioun on his prey, whanne the multitude of schipherdis cometh ayens hym, he schal not drede of the vois of hem, and he schal not drede of the multitude of hem; so the Lord of oostis schal come doun, for to fiyte on the mounteyn of Sion, and on the litil hil therof.", "rotherham": "For Thus, hath Yahweh said unto me—Like as a lion or a young lion growleth over his prey. Who—though there be called out against him a multitude of shepherds—Will not at their voice, be dismayed, Nor, at their noise, be daunted, So, will Yahweh of hosts come down, to make war over Mount Zion, and over the hill thereof.", "darby": "For thus hath Jehovah said unto me: Like as the lion and the young lion growling over his prey, when a multitude of shepherds is called forth against him, is not afraid of their voice, nor giveth way before the multitude of them; so will Jehovah of hosts come down to war upon mount Zion, and on the hill thereof.", "twenty": "", "jps": "For thus saith HaShem unto me: Like as the lion, or the young lion, growling over his prey, though a multitude of shepherds be called forth against him, will not be dismayed at their voice, nor abase himself for the noise of them; so will HaShem of hosts come down to fight upon mount Zion, and upon the hill thereof.", "acv": "For thus says Jehovah to me, As the lion and the young lion growling over his prey, even if a multitude of shepherds are called forth against him, he will not be dismayed at their voice, nor abase himself for the noise of them, so Jehovah of hosts will come down to fight upon mount Zion, and upon the hill of it.", "anderson": "", "haweis": "", "noyes": "For thus hath Jehovah said to me: As when the lion and the young lion growl over their prey, And a multitude of shepherds is called forth against him, By their noise he is not terrified, Nor by their tumult disheartened; So shall Jehovah of hosts come down to fight for mount Zion, and her hill.", "webster": "For thus hath the LORD spoken to me, As the lion and the young lion roaring on his prey, when a multitude of shepherds is called forth against him, [he] will not be afraid of their voice, nor abase himself for the noise of them: so will the LORD of hosts come down to fight for mount Zion, and for the hill thereof.", "vulgate": "quia haec dicit Dominus ad me quomodo si rugiat leo et catulus leonis super praedam suam cum occurrerit ei multitudo pastorum a voce eorum non formidabit et a multitudine eorum non pavebit sic descendet Dominus exercituum ut proelietur super montem Sion et super collem eius;", "brenton": "For thus said the Lord to me, As a lion would roar, or a lion's whelp over prey which he has taken, and cry over it, until the mountains are filled with his voice, and the animals are awe-struck and tremble at the fierceness of his wrath: so the Lord of hosts shall descend to fight upon the mount Sion, even upon her mountains."}}, {"v": 5, "ref": "31:5", "o": "כְּ/צִפֳּרִ֣ים עָפ֔וֹת כֵּ֗ן יָגֵ֛ן יְהוָ֥ה צְבָא֖וֹת עַל יְרֽוּשָׁלִָ֑ם גָּנ֥וֹן וְ/הִצִּ֖יל פָּסֹ֥חַ וְ/הִמְלִֽיט", "en": {"kjv": "As birds flying, so will the Lord of hosts defend Jerusalem; defending also he will deliver it; and passing over he will preserve it.", "web": "As birds hovering, so Yahweh of Armies will protect Jerusalem. He will protect and deliver it. He will pass over and preserve it.”", "bsb": "Like birds hovering overhead, so the LORD of Hosts will protect Jerusalem. He will shield it and deliver it; He will pass over it and preserve it.”", "asv": "As birds hovering, so will Jehovah of hosts protect Jerusalem; he will protect and deliver it, he will pass over and preserve it.", "ylt": "As birds flying, so doth Jehovah of Hosts Cover over Jerusalem, covering and delivering, Passing over, and causing to escape.'", "dra": "As birds flying, so will the Lord of hosts protect Jerusalem, protecting and delivering, passing over and saving.", "bbe": "Like birds with outstretched wings, so will the Lord of armies be a cover to Jerusalem; he will be a cover and salvation for it, going over it he will keep it from danger.", "geneva": "As birds that flie, so shall the Lord of hostes defend Ierusalem by defending and deliuering, by passing through and preseruing it.", "wycliffe": "As briddis fleynge, so the Lord of oostis schal defende Jerusalem; he defendynge and delyuerynge, passynge forth and sauynge.", "rotherham": "As little mother-birds hovering, so, will Yahweh of hosts throw a covering over Jerusalem,—Covering, so will he rescue, Passing over, so will he deliver!", "darby": "As birds with outstretched wings, so will Jehovah of hosts cover Jerusalem; covering, he will also deliver, passing over, he will rescue [it].", "twenty": "", "jps": "As birds hovering, so will HaShem of hosts protect Jerusalem; He will deliver it as He protecteth it, He will rescue it as He passeth over.", "acv": "As birds hovering, so Jehovah of hosts will protect Jerusalem. He will protect and deliver. He will pass over and preserve.", "anderson": "", "haweis": "", "noyes": "As birds hover over their young, So shall Jehovah of hosts defend Jerusalem; He will defend and deliver, spare and save.", "webster": "As birds flying, so will the LORD of hosts defend Jerusalem; defending also he will deliver [it]; [and] passing over he will preserve [it].", "vulgate": "sicut aves volantes sic proteget Dominus exercituum Hierusalem protegens et liberans transiens et salvans;", "brenton": "As birds flying, so shall the Lord of hosts defend; he shall defend Jerusalem, and he shall rescue, and save and deliver."}}, {"v": 6, "ref": "31:6", "o": "שׁ֗וּבוּ לַ/אֲשֶׁ֛ר הֶעְמִ֥יקוּ סָרָ֖ה בְּנֵ֥י יִשְׂרָאֵֽל", "en": {"kjv": "Turn ye unto him from whom the children of Israel have deeply revolted.", "web": "Return to him from whom you have deeply revolted, children of Israel.", "bsb": "Return to the One against whom you have so blatantly rebelled, O children of Israel.", "asv": "Turn ye unto him from whom ye have deeply revolted, O children of Israel.", "ylt": "Turn back to Him from whom sons of Israel Have deepened apostasy.", "dra": "Return as you had deeply revolted, O children of Israel.", "bbe": "Come back to him who has been so deeply sinned against by the children of Israel.", "geneva": "O ye children of Israel, turne againe, in as much as ye are sunken deepe in rebellion.", "wycliffe": "Ye sones of Israel, be conuertid, as ye hadden go awei in to depthe.", "rotherham": "Return ye unto him against whom the sons of Israel have deeply revolted,", "darby": "Turn unto him from whom ye have deeply revolted, ye children of Israel;", "twenty": "", "jps": "Turn ye unto Him against whom ye have deeply rebelled, O children of Israel.", "acv": "Turn ye to him from whom ye have deeply revolted, O sons of Israel.", "anderson": "", "haweis": "", "noyes": "Turn, O ye children of Israel, To him from whom ye have so deeply revolted! For in that day shall every one cast away his idols of", "webster": "Turn ye to [him from] whom the children of Israel have deeply revolted.", "vulgate": "convertimini sicut in profundum recesseratis filii Israhel;", "brenton": "Turn, ye children of Israel, who devise a deep and sinful counsel."}}, {"v": 7, "ref": "31:7", "o": "כִּ֚י בַּ/יּ֣וֹם הַ/ה֔וּא יִמְאָס֗וּ/ן אִ֚ישׁ אֱלִילֵ֣י כַסְפּ֔/וֹ וֶ/אֱלִילֵ֖י זְהָב֑/וֹ אֲשֶׁ֨ר עָשׂ֥וּ לָ/כֶ֛ם יְדֵי/כֶ֖ם חֵֽטְא", "en": {"kjv": "For in that day every man shall cast away his idols of silver, and his idols of gold, which your own hands have made unto you for a sin.", "web": "For in that day everyone shall cast away his idols of silver and his idols of gold—sin which your own hands have made for you.", "bsb": "For on that day, every one of you will reject the idols of silver and gold that your own hands have sinfully made.", "asv": "For in that day they shall cast away every man his idols of silver, and his idols of gold, which your own hands have made unto you for a sin.", "ylt": "For in that day despise doth each His idols of silver, and his idols of gold, That your hands made to you--a sin.", "dra": "For in that day a man shall cast away his idols of silver, and his idols of gold, which your hands have made for you to sin.", "bbe": "For in that day they will all give up their images of silver and of gold, the sin which they made for themselves.", "geneva": "For in that day euery man shall cast out his idoles of siluer, and his idoles of golde, which your handes haue made you, euen a sinne.", "wycliffe": "Forsothe in that dai a man schal caste awei the idols of his siluer, and the idols of his gold, whiche youre hondis maden to you in to synne.", "rotherham": "For in that day, will every man reject his idols of silver, and his idols of gold,—Which your hands had made for you as a sin!", "darby": "for in that day every man shall cast away his idols of silver and his idols of gold, which your sinful hands have made unto you.", "twenty": "", "jps": "For in that day they shall cast away every man his idols of silver, and his idols of gold, which your own hands have made unto you for a sin.", "acv": "For in that day they shall cast away every man his idols of silver, and his idols of gold, which your own hands have made to you for a sin.", "anderson": "", "haweis": "", "noyes": "silver and his idols of gold, Which your hands have made for sin.", "webster": "For in that day every man shall cast away his idols of silver, and his idols of gold, which your own hands have made to you [for] a sin.", "vulgate": "in die enim illa abiciet vir idola argenti sui et idola auri sui quae fecerunt vobis manus vestrae in peccatum;", "brenton": "For in that day men shall renounce their silver idols and their golden idols, which their hands made."}}, {"v": 8, "ref": "31:8", "o": "וְ/נָפַ֤ל אַשּׁוּר֙ בְּ/חֶ֣רֶב לֹא אִ֔ישׁ וְ/חֶ֥רֶב לֹֽא אָדָ֖ם תֹּֽאכֲלֶ֑/נּוּ וְ/נָ֥ס ל/וֹ֙ מִ/פְּנֵי חֶ֔רֶב וּ/בַחוּרָ֖י/ו לָ/מַ֥ס יִהְיֽוּ", "en": {"kjv": "Then shall the Assyrian fall with the sword, not of a mighty man; and the sword, not of a mean man, shall devour him: but he shall flee from the sword, and his young men shall be discomfited.", "web": "“The Assyrian will fall by the sword, not of man; and the sword, not of mankind, shall devour him. He will flee from the sword, and his young men will become subject to forced labor.", "bsb": "“Then Assyria will fall, but not by the sword of man; a sword will devour them, but not one made by mortals. They will flee before the sword, and their young men will be put to forced labor.", "asv": "And the Assyrian shall fall by the sword, not of man; and the sword, not of men, shall devour him; and he shall flee from the sword, and his young men shall become subject to taskwork.", "ylt": "And fallen hath Asshur by sword, not of the high, Yea, a sword--not of the low, doth consume him, And he hath fled for himself from the face of a sword, And his young men become tributary.", "dra": "And the Assyrian shall fall by the sword not of a man, and the sword not of a man shall devour him, and he shall flee not at the face of the sword, and his young men shall be tributaries.", "bbe": "Then the Assyrian will come down by the sword, but not of man; the sword, not of men, will be the cause of his destruction: and he will go in flight from the sword, and his young men will be put to forced work.", "geneva": "Then shall Asshur fall by the sworde, not of man, neither shall the sworde of man deuoure him, and hee shall flee from the sworde, and his yong men shall faint.", "wycliffe": "And Assur schal falle bi swerd, not of man, and a swerd, not of man, schal deuoure hym; and he schal fle, not fro the face of swerd, and hise yonge men schulen be tributaries;", "rotherham": "Then shall the Assyrian fall, by the sword, not of a great man, And the sword, not of a mean man, shall devour him,—Howbeit he shall take his flight from the face of a sword, And his young men, shall come under tribute;", "darby": "And Asshur shall fall by the sword, not of a great man; and the sword, not of a mean man, shall devour him: and he shall flee from the sword, and his young men shall become tributary;", "twenty": "", "jps": "Then shall Asshur fall with the sword, not of man, and the sword, not of men, shall devour him; and he shall flee from the sword, and his young men shall become tributary.", "acv": "And the Assyrian shall fall by the sword, not of man, and the sword, not of men, shall devour him. But he shall flee from the sword, and his young men shall become subject to task work.", "anderson": "", "haweis": "", "noyes": "The Assyrian shall fall by a sword not of man, Yea, a sword not of mortal shall devour him; He shall flee before the sword, And his young warriors shall be slaves.", "webster": "Then shall the Assyrian fall with the sword, not of a mighty man; and the sword, not of a mean man, shall devour him: but he shall flee from the sword, and his young men shall be discomfited.", "vulgate": "et cadet Assur in gladio non viri et gladius non hominis vorabit eum et fugiet non a facie gladii et iuvenes eius vectigales erunt;", "brenton": "And the Assyrian shall fall: not the sword of a great man, nor the sword of a mean man shall devour him; neither shall he flee from the face of the sword: but the young men shall be overthrown:"}}, {"v": 9, "ref": "31:9", "o": "וְ/סַלְע/וֹ֙ מִ/מָּג֣וֹר יַֽעֲב֔וֹר וְ/חַתּ֥וּ מִ/נֵּ֖ס שָׂרָ֑י/ו נְאֻם יְהוָ֗ה אֲשֶׁר א֥וּר ל/וֹ֙ בְּ/צִיּ֔וֹן וְ/תַנּ֥וּר ל֖/וֹ בִּ/ירוּשָׁלִָֽם", "en": {"kjv": "And he shall pass over to his strong hold for fear, and his princes shall be afraid of the ensign, saith the Lord, whose fire is in Zion, and his furnace in Jerusalem.", "web": "His rock will pass away by reason of terror, and his princes will be afraid of the banner,” says Yahweh, whose fire is in Zion, and his furnace in Jerusalem.", "bsb": "Their rock will pass away for fear, and their princes will panic at the sight of the battle standard,” declares the LORD, whose fire is in Zion, whose furnace is in Jerusalem.", "asv": "And his rock shall pass away by reason of terror, and his princes shall be dismayed at the ensign, saith Jehovah, whose fire is in Zion, and his furnace in Jerusalem.", "ylt": "And to his rock from fear he passeth on, And affrighted by the ensign have been his princes--an affirmation of Jehovah, Who hath a light in Zion, And who hath a furnace in Jerusalem!", "dra": "And his strength shall pass away with dread, and his princes fleeing shall be afraid: the Lord hath said it, whose fire is in Sion, and his furnace in Jerusalem.", "bbe": "And his rock will come to nothing because of fear, and his chiefs will go in flight from the flag, says the Lord, whose fire is in Zion, and his altar in Jerusalem.", "geneva": "And he shall go for feare to his towre, and his princes shall be afraide of the standart, sayeth the Lord, whose fire is in Zion, and his fornace in Ierusalem.", "wycliffe": "and the strengthe of hym schal passe fro ferdfulnesse, and hise princes fleynge schulen drede. The Lord seide, whos fier is in Sion, and his chymeney is in Jerusalem.", "rotherham": "And his own Cliff, through terror, shall he pass by, And his princes shall be dismayed at an ensign,—Declareth Yahweh. Who hath a flame in Zion, And hath a furnace in Jerusalem.", "darby": "and for fear, he shall pass over to his rock, and his princes shall be afraid of the banner, saith Jehovah, whose fire is in Zion, and his furnace in Jerusalem.", "twenty": "", "jps": "And his rock shall pass away by reason of terror, and his princes shall be dismayed at the ensign, saith HaShem, whose fire is in Zion, and His furnace in Jerusalem.", "acv": "And his rock shall pass away because of terror, and his rulers shall be dismayed at the ensign, says Jehovah, whose fire is in Zion, and his furnace in Jerusalem.", "anderson": "", "haweis": "", "noyes": "Through fear shall he pass beyond his stronghold, And his princes shall be afraid of the standard. Thus saith Jehovah, who hath his fire in Zion, And his furnace in Jerusalem.", "webster": "And he shall pass over to his strong hold for fear, and his princes shall be afraid of the ensign, saith the LORD, whose fire [is] in Zion, and his furnace in Jerusalem.", "vulgate": "et fortitudo eius a terrore transibit et pavebunt fugientes principes eius dixit Dominus cuius ignis est in Sion et caminus eius in Hierusalem;", "brenton": "for they shall be compassed with rocks as with a trench, and shall be worsted; and he that flees shall be taken. Thus saith the Lord, Blesses is he that has a seed in Sion, and household friends in Jerusalem."}}]}, {"c": 32, "verses": [{"v": 1, "ref": "32:1", "o": "הֵ֥ן לְ/צֶ֖דֶק יִמְלָךְ מֶ֑לֶךְ וּ/לְ/שָׂרִ֖ים לְ/מִשְׁפָּ֥ט יָשֹֽׂרוּ", "en": {"kjv": "Behold, a king shall reign in righteousness, and princes shall rule in judgment.", "web": "Behold, a king shall reign in righteousness, and princes shall rule in justice.", "bsb": "Behold, a king will reign in righteousness, and princes will rule with justice.", "asv": "Behold, a king shall reign in righteousness, and princes shall rule in justice.", "ylt": "Lo, for righteousness doth a king reign, As to princes, for judgment they rule.", "dra": "Behold a king shall reign in justice, and princes shall rule in judgment.", "bbe": "See, a king will be ruling in righteousness, and chiefs will give right decisions.", "geneva": "Behold, a King shall reigne in iustice, and the princes shall rule in iudgement.", "wycliffe": "Lo! the kyng schal regne in riytfulnesse, and princes schulen be souereyns in doom.", "rotherham": "Lo! in righteousness, shall reign a king, Yea even princes, with equity, shall bear rule.", "darby": "Behold, a king shall reign in righteousness, and princes shall rule in judgment.", "twenty": "", "jps": "Behold, a king shall reign in righteousness, and as for princes, they shall rule in justice.", "acv": "Behold, a king shall reign in righteousness, and rulers shall rule in justice.", "anderson": "", "haweis": "", "noyes": "Behold! a king shall reign in righteousness, And princes shall rule with equity.", "webster": "Behold, a king shall reign in righteousness, and princes shall rule in judgment.", "vulgate": "ecce in iustitia regnabit rex et principes in iudicio praeerunt;", "brenton": "For, behold, a righteous king shall reign, and princes shall govern with judgment."}}, {"v": 2, "ref": "32:2", "o": "וְ/הָיָה אִ֥ישׁ כְּ/מַֽחֲבֵא ר֖וּחַ וְ/סֵ֣תֶר זָ֑רֶם כְּ/פַלְגֵי מַ֣יִם בְּ/צָי֔וֹן כְּ/צֵ֥ל סֶֽלַע כָּבֵ֖ד בְּ/אֶ֥רֶץ עֲיֵפָֽה", "en": {"kjv": "And a man shall be as an hiding place from the wind, and a covert from the tempest; as rivers of water in a dry place, as the shadow of a great rock in a weary land.", "web": "A man shall be as a hiding place from the wind, and a covert from the storm, as streams of water in a dry place, as the shade of a large rock in a weary land.", "bsb": "Each will be like a shelter from the wind, a refuge from the storm, like streams of water in a dry land, like the shadow of a great rock in an arid land.", "asv": "And a man shall be as a hiding-place from the wind, and a covert from the tempest, as streams of water in a dry place, as the shade of a great rock in a weary land.", "ylt": "And each hath been as a hiding-place from wind, And as a secret hiding-place from inundation, As rivulets of waters in a dry place, As a shadow of a heavy rock in a weary land.", "dra": "And a man shall be as when one is hid from the wind, and hideth himself from a storm, as rivers of waters in drought, and the shadow of a rock that standeth out in a desert land.", "bbe": "And a man will be as a safe place from the wind, and a cover from the storm; as rivers of water in a dry place, as the shade of a great rock in a waste land.", "geneva": "And that man shall bee as an hiding place from the winde, and as a refuge for the tempest: as riuers of water in a drie place, and as the shadowe of a great rocke in a weary land.", "wycliffe": "And a man schal be, as he that is hid fro wynd, and hidith hym silf fro tempest; as stremes of watris in thirst, and the schadewe of a stoon stondynge fer out in a desert lond.", "rotherham": "So shall each one become As a hiding-place from the wind And a covert from the storm,—As channels of water in a dry place, As the shadow of a massive cliff in a weary land.", "darby": "And a man shall be as a hiding-place from the wind, and a covert from the storm; as brooks of water in a dry place, as the shadow of a great rock in a thirsty land.", "twenty": "", "jps": "And a man shall be as in a hiding-place from the wind, and a covert from the tempest; as by the watercourses in a dry place, as in the shadow of a great rock in a weary land.", "acv": "And a man shall be as a hiding-place from the wind, and a covert from the tempest, as streams of water in a dry place, as the shade of a great rock in a weary land.", "anderson": "", "haweis": "", "noyes": "Every one of them shall be a hiding-place from the wind, And a shelter from the tempest; As streams of water in a dry place, As the shadow of a great rock in a weary land.", "webster": "And a man shall be as a hiding-place from the wind, and a covert from the tempest; as streams of water in a dry place, as the shade of a great rock in a weary land.", "vulgate": "et erit vir sicut qui absconditur a vento et celat se a tempestate sicut rivi aquarum in siti et umbra petrae prominentis in terra deserta;", "brenton": "And a man shall hide his words, and be hidden, as from rushing water, and shall appear in Sion as a rushing river, glorious in a thirsty land."}}, {"v": 3, "ref": "32:3", "o": "וְ/לֹ֥א תִשְׁעֶ֖ינָה עֵינֵ֣י רֹאִ֑ים וְ/אָזְנֵ֥י שֹׁמְעִ֖ים תִּקְשַֽׁבְנָה", "en": {"kjv": "And the eyes of them that see shall not be dim, and the ears of them that hear shall hearken.", "web": "The eyes of those who see will not be dim, and the ears of those who hear will listen.", "bsb": "Then the eyes of those who see will no longer be closed, and the ears of those who hear will listen.", "asv": "And the eyes of them that see shall not be dim, and the ears of them that hear shall hearken.", "ylt": "And not dazzled are the eyes of beholders, And the ears of hearers do attend.", "dra": "The eyes of them that see shall not be dim, and the ears of them that hear shall hearken diligently.", "bbe": "And the eyes of those who see will not be shut, and those who have hearing will give ear to the word.", "geneva": "The eyes of the seeing shall not be shut, and the eares of them that heare, shall hearken.", "wycliffe": "The iyen of profetis schulen not dasewe, and the eeris of heereris schulen herke diligentli;", "rotherham": "And the eyes of them who are ready to see, shall not be closed,—And, the ears of them who are ready to hear, shall hearken;", "darby": "And the eyes of them that see shall not be dim, and the ears of them that hear shall hearken;", "twenty": "", "jps": "And the eyes of them that see shall not be closed, and the ears of them that hear shall attend.", "acv": "And the eyes of those who see shall not be dim, and the ears of those who hear shall hearken.", "anderson": "", "haweis": "", "noyes": "The eyes of them that see shall no more be blind, And the ears of them that hear shall hearken.", "webster": "And the eyes of them that see shall not be dim, and the ears of them that hear shall hearken.", "vulgate": "non caligabunt oculi videntium et aures audientium diligenter auscultabunt;", "brenton": "And they shall no more trust in men, but they shall incline their ears to hear."}}, {"v": 4, "ref": "32:4", "o": "וּ/לְבַ֥ב נִמְהָרִ֖ים יָבִ֣ין לָ/דָ֑עַת וּ/לְשׁ֣וֹן עִלְּגִ֔ים תְּמַהֵ֖ר לְ/דַבֵּ֥ר צָחֽוֹת", "en": {"kjv": "The heart also of the rash shall understand knowledge, and the tongue of the stammerers shall be ready to speak plainly.", "web": "The heart of the rash will understand knowledge, and the tongue of the stammerers will be ready to speak plainly.", "bsb": "The mind of the rash will know and understand, and the stammering tongue will speak clearly and fluently.", "asv": "And the heart of the rash shall understand knowledge, and the tongue of the stammerers shall be ready to speak plainly.", "ylt": "And the heart of those hastened Understandeth to know, And the tongue of stammerers hasteth to speak clearly.", "dra": "And the heart of fools shall understand knowledge, and the tongue of stammerers shall speak readily and plain.", "bbe": "The man of sudden impulses will become wise in heart, and he whose tongue is slow will get the power of talking clearly.", "geneva": "And the heart of the foolish shall vnderstand knowledge, and the tongue of the stutters shalbe ready to speake distinctly.", "wycliffe": "and the herte of foolis schal vndurstonde kunnyng, and the tunge of stuttynge men schal speke swiftli, and pleynli.", "rotherham": "And the heart of the hurried, shall take note of knowledge, And the tongue of stammerers, shall make haste to speak plainly.", "darby": "and the heart of the rash shall understand knowledge, and the tongue of the stammerers shall be ready to speak plainly.", "twenty": "", "jps": "The heart also of the rash shall understand knowledge, and the tongue of the stammerers shall be ready to speak plainly.", "acv": "And the heart of the rash shall understand knowledge, and the tongue of the stammerers shall be ready to speak plainly.", "anderson": "", "haweis": "", "noyes": "The heart of the rash shall gain wisdom, And the tongue of the stammerer learn to speak plainly.", "webster": "The heart also of the rash shall understand knowledge, and the tongue of the stammerers shall be ready to speak plainly.", "vulgate": "et cor stultorum intelleget scientiam et lingua balborum velociter loquetur et plane;", "brenton": "And the heart of the weak ones shall attend to hear, and the stammering tongues shall soon learn to speak peace."}}, {"v": 5, "ref": "32:5", "o": "לֹֽא יִקָּרֵ֥א ע֛וֹד לְ/נָבָ֖ל נָדִ֑יב וּ/לְ/כִילַ֕י לֹ֥א יֵֽאָמֵ֖ר שֽׁוֹעַ", "en": {"kjv": "The vile person shall be no more called liberal, nor the churl said to be bountiful.", "web": "The fool will no longer be called noble, nor the scoundrel be highly respected.", "bsb": "No longer will a fool be called noble, nor a scoundrel be respected.", "asv": "The fool shall be no more called noble, nor the churl said to be bountiful.", "ylt": "A fool is no more called `noble,' And to a miser it is not said, `rich;'", "dra": "The fool shall no more be called prince: neither shall the deceitful be called great:", "bbe": "The foolish man will no longer be named noble, and they will not say of the false man that he is a man of honour.", "geneva": "A nigard shall no more be called liberall, nor the churle riche.", "wycliffe": "He that is vnwijs, schal no more be clepid prince, and a gileful man schal not be clepid the grettere.", "rotherham": "A base man, shall no longer be called, noble,—Nor, a knave, be named, liberal;", "darby": "The vile man shall be no more called noble, nor the churl said to be bountiful:", "twenty": "", "jps": "The vile person shall be no more called liberal, nor the churl said to be noble.", "acv": "The fool shall no more be called noble, nor the churl said to be bountiful.", "anderson": "", "haweis": "", "noyes": "The vile shall no more be called liberal, Nor the niggard said to be bountiful;", "webster": "The vile person shall be no more called liberal, nor the churl said [to be] bountiful.", "vulgate": "non vocabitur ultra is qui insipiens est princeps neque fraudulentus appellabitur maior;", "brenton": "And they shall no more at all tell a fool to rule, and thy servants shall no more at all say, Be silent."}}, {"v": 6, "ref": "32:6", "o": "כִּ֤י נָבָל֙ נְבָלָ֣ה יְדַבֵּ֔ר וְ/לִבּ֖/וֹ יַעֲשֶׂה אָ֑וֶן לַ/עֲשׂ֣וֹת חֹ֗נֶף וּ/לְ/דַבֵּ֤ר אֶל יְהוָה֙ תּוֹעָ֔ה לְ/הָרִיק֙ נֶ֣פֶשׁ רָעֵ֔ב וּ/מַשְׁקֶ֥ה צָמֵ֖א יַחְסִֽיר", "en": {"kjv": "For the vile person will speak villany, and his heart will work iniquity, to practise hypocrisy, and to utter error against the Lord, to make empty the soul of the hungry, and he will cause the drink of the thirsty to fail.", "web": "For the fool will speak folly, and his heart will work iniquity, to practice profanity, and to utter error against Yahweh, To make empty the soul of the hungry, and to cause the drink of the thirsty to fail.", "bsb": "For a fool speaks foolishness; his mind plots iniquity. He practices ungodliness and speaks falsely about the LORD; he leaves the hungry empty and deprives the thirsty of drink.", "asv": "For the fool will speak folly, and his heart will work iniquity, to practise profaneness, and to utter error against Jehovah, to make empty the soul of the hungry, and to cause the drink of the thirsty to fail.", "ylt": "For a fool speaketh folly, And his heart doth iniquity, to do profanity, And to speak concerning Jehovah error, To empty the soul of the hungry, Yea, drink of the thirsty he causeth to lack.", "dra": "For the fool will speak foolish things, and his heart will work iniquity, to practise hypocrisy, and speak to the Lord deceitfully, and to make empty the soul of the hungry, and take away drink from the thirsty.", "bbe": "For the foolish man will say foolish things, having evil thoughts in his heart, working what is unclean, and talking falsely about the Lord, to keep food from him who is in need of it, and water from him whose soul is desiring it.", "geneva": "But the nigarde will speake of nigardnesse, and his heart will worke iniquitie, and do wickedly, and speake falsely against the Lord, to make emptie the hungrie soule, and to cause the drinke of the thirstie to faile.", "wycliffe": "Forsothe a fool shal speke foli thingis, and his herte schal do wickidnesse, that he performe feynyng, and speke to the Lord gilefuli; and he schal make voide the soule of an hungry man, and schal take awei drynke fro a thirsti man.", "rotherham": "For, a base man, with baseness, will speak, And, his heart, will practise iniquity,—Practising profanity, And speaking, against Yahweh that which misleadeth, Emptying the soul of the hungry, And the drink of the thirsty, he causeth to fail;", "darby": "for the vile man will speak villainy, and his heart will work iniquity, to practise hypocrisy, and to utter error against Jehovah, to make empty the soul of the hungry, and to cause the drink of the thirsty to fail.", "twenty": "", "jps": "For the vile person will speak villainy, and his heart will work iniquity, to practise ungodliness, and to utter wickedness against HaShem, to make empty the soul of the hungry, and to cause the drink of the thirsty to fail.", "acv": "For the fool will speak folly, and his heart will work iniquity, to practice profaneness, and to utter error against Jehovah, to make empty the soul of the hungry, and to cause the drink of the thirsty to fail.", "anderson": "", "haweis": "", "noyes": "For the vile will still utter villany, And his heart will devise iniquity; He will practise deception, and speak impiety against God; He will take away the food of the hungry, And deprive the thirsty of drink.", "webster": "For the vile person will speak villainy, and his heart will work iniquity, to practice hypocrisy, and to utter error against the LORD, to make empty the soul of the hungry; and he will cause the drink of the thirsty to fail.", "vulgate": "stultus enim fatua loquetur et cor eius faciet iniquitatem ut perficiat simulationem et loquatur ad Dominum fraudulenter et vacuefaciat animam esurientis et potum sitienti auferat;", "brenton": "For the fool shall speak foolish words, and his heart shall meditate vanities, and to perform lawless deeds and to speak error against the Lord, to scatter hungry souls, and he will cause the thirsty souls to be empty."}}, {"v": 7, "ref": "32:7", "o": "וְ/כֵלַ֖י כֵּלָ֣י/ו רָעִ֑ים ה֚וּא זִמּ֣וֹת יָעָ֔ץ לְ/חַבֵּ֤ל ענוים עֲנִיִּים֙ בְּ/אִמְרֵי שֶׁ֔קֶר וּ/בְ/דַבֵּ֥ר אֶבְי֖וֹן מִשְׁפָּֽט", "en": {"kjv": "The instruments also of the churl are evil: he deviseth wicked devices to destroy the poor with lying words, even when the needy speaketh right.", "web": "The ways of the scoundrel are evil. He devises wicked devices to destroy the humble with lying words, even when the needy speaks right.", "bsb": "The weapons of the scoundrel are destructive; he hatches plots to destroy the poor with lies, even when the plea of the needy is just.", "asv": "And the instruments of the churl are evil: he deviseth wicked devices to destroy the meek with lying words, even when the needy speaketh right.", "ylt": "And the miser--his instruments are evil, He hath counselled wicked devices, To corrupt the poor with lying sayings, Even when the needy speaketh justly.", "dra": "The vessels of the deceitful are most wicked: for he hath framed devices to destroy the meek, with lying words, when the poor man speaketh judgment.", "bbe": "The designs of the false are evil, purposing the destruction of the poor man by false words, even when he is in the right.", "geneva": "For the weapons of the churle are wicked: hee deuiseth wicked counsels, to vndoe the poore with lying words: and to speake against the poore in iudgement.", "wycliffe": "The vessels of a gileful man ben worste; for he schal make redi thouytis to leese mylde men in the word of a leesyng, whanne a pore man spak doom.", "rotherham": "Yea, a knave, his weapons are wicked,—He, base schemes, hath devised To ruin the oppressed with speeches of falsehood Even when the needy pleadeth, for justice.", "darby": "The instruments also of the churl are evil: he deviseth wicked devices to destroy the meek with lying words, even when the needy speaketh right.", "twenty": "", "jps": "The instruments also of the churl are evil; he deviseth wicked devices to destroy the poor with lying words, and the needy when he speaketh right.", "acv": "And the instruments of the churl are evil. He devises wicked devices to destroy the poor with lying words, even when the needy speaks right.", "anderson": "", "haweis": "", "noyes": "The instruments also of the niggard are evil; He plotteth mischievous devices, To destroy the poor with lying words, Even when the cause of the needy is just.", "webster": "The instruments also of the churl [are] evil: he deviseth wicked devices to destroy the poor with lying words, even when the needy speaketh right.", "vulgate": "fraudulenti vasa pessima sunt ipse enim cogitationes concinnavit ad perdendos mites in sermone mendacii cum loqueretur pauper iudicium;", "brenton": "For the counsel of the wicked will devise iniquity, to destroy the poor with unjust words, and ruin the cause of the poor in judgment."}}, {"v": 8, "ref": "32:8", "o": "וְ/נָדִ֖יב נְדִיב֣וֹת יָעָ֑ץ וְ/ה֖וּא עַל נְדִיב֥וֹת יָקֽוּם", "en": {"kjv": "But the liberal deviseth liberal things; and by liberal things shall he stand.", "web": "But the noble devises noble things; and he will continue in noble things.", "bsb": "But a noble man makes honorable plans; he stands up for worthy causes.", "asv": "But the noble deviseth noble things; and in noble things shall he continue.", "ylt": "And the noble counselled noble things, And he for noble things riseth up.", "dra": "But the prince will devise such things as are worthy of a prince, and he shall stand above the rulers.", "bbe": "But the noble-hearted man has noble purposes, and by these he will be guided.", "geneva": "But the liberall man will deuise of liberall things, and he will continue his liberalitie.", "wycliffe": "Forsothe a prince schal thenke tho thingis that ben worthi to a prince, and he schal stonde ouer duykis.", "rotherham": "But, a noble man, noble things, hath devised,—And, he, upon noble things, will stand,", "darby": "But the noble deviseth noble things; and to noble things doth he stand.", "twenty": "", "jps": "But the liberal deviseth liberal things; and by liberal things shall he stand.", "acv": "But a noble man devises noble things, and in noble things he shall continue.", "anderson": "", "haweis": "", "noyes": "But the liberal deviseth liberal things, And in liberal things will he persevere.", "webster": "But the liberal deviseth liberal things; and by liberal things shall he stand.", "vulgate": "princeps vero ea quae digna sunt principe cogitavit et ipse super duces stabit;", "brenton": "But the godly have devised wise measures, and this counsel shall stand."}}, {"v": 9, "ref": "32:9", "o": "נָשִׁים֙ שַֽׁאֲנַנּ֔וֹת קֹ֖מְנָה שְׁמַ֣עְנָה קוֹלִ֑/י בָּנוֹת֙ בֹּֽטח֔וֹת הַאְזֵ֖נָּה אִמְרָתִֽ/י", "en": {"kjv": "Rise up, ye women that are at ease; hear my voice, ye careless daughters; give ear unto my speech.", "web": "Rise up, you women who are at ease! Hear my voice! You careless daughters, give ear to my speech!", "bsb": "Stand up, you complacent women; listen to me. Give ear to my word, you overconfident daughters.", "asv": "Rise up, ye women that are at ease, andhear my voice; ye careless daughters, give ear unto my speech.", "ylt": "Women, easy ones, rise, hear my voice, Daughters, confident ones, give ear to my saying,", "dra": "Rise up, ye rich women, and hear my voice: ye confident daughters, give ear to my speech.", "bbe": "Give ear to my voice, you women who are living in comfort; give attention to my words, you daughters who have no fear of danger.", "geneva": "Rise vp, ye women that are at ease: heare my voyce, ye carelesse daughters: hearken to my wordes.", "wycliffe": "Riche wymmen, rise ye, and here my vois; douytris tristynge, perseyue ye with eeris my speche.", "rotherham": "Ye women in comfort! arise hear my voice, Ye daughters so confident give ear to my speech:—", "darby": "Rise up, ye women that are at ease, hear my voice; ye careless daughters, give ear unto my speech.", "twenty": "", "jps": "Rise up, ye women that are at ease, and hear my voice; ye confident daughters, give ear unto my speech.", "acv": "Rise up, ye women who are at ease. Hear my voice, ye careless daughters. Give ear to my speech.", "anderson": "", "haweis": "", "noyes": "Arise, hear my voice, ye women that are at ease! Give ear to my speech, ye careless daughters!", "webster": "Rise up, ye women that are at ease; hear my voice, ye careless daughters; give ear to my speech.", "vulgate": "mulieres opulentae surgite et audite vocem meam filiae confidentes percipite auribus eloquium meum;", "brenton": "Rise up, ye rich women, and hear my voice; ye confident daughters, hearken to my words."}}, {"v": 10, "ref": "32:10", "o": "יָמִים֙ עַל שָׁנָ֔ה תִּרְגַּ֖זְנָה בֹּֽטְח֑וֹת כִּ֚י כָּלָ֣ה בָצִ֔יר אֹ֖סֶף בְּלִ֥י יָבֽוֹא", "en": {"kjv": "Many days and years shall ye be troubled, ye careless women: for the vintage shall fail, the gathering shall not come.", "web": "For days beyond a year you will be troubled, you careless women; for the vintage shall fail. The harvest won’t come.", "bsb": "In a little more than a year you will tremble, O secure ones. For the grape harvest will fail and the fruit harvest will not arrive.", "asv": "For days beyond a year shall ye be troubled, ye careless women; for the vintage shall fail, the ingathering shall not come.", "ylt": "Days and a year ye are troubled, O confident ones, For consumed hath been harvest, The gathering cometh not.", "dra": "For after days and a year, you that are confident shall be troubled: for the vintage is at an end, the gathering shall come no more.", "bbe": "In not much more than a year, you, who are not looking for evil, will be troubled: for the produce of the vine-gardens will be cut off, and there will be no getting in of the grapes.", "geneva": "Yee women, that are carelesse, shall be in feare aboue a yeere in dayes: for the vintage shall faile, and the gatherings shall come no more.", "wycliffe": "For whi aftir daies and a yeer, and ye that tristen schulen be disturblid; for whi vyndage is endid, gaderyng schal no more come.", "rotherham": "Some days beyond a year, ye shall be troubled ye confident ones,—For failed hath the vintage, No, gathering, cometh in.", "darby": "In a year and [some] days shall ye be troubled, ye careless women; for the vintage shall fail, the ingathering shall not come.", "twenty": "", "jps": "After a year and days shall ye be troubled, ye confident women; for the vintage shall fail, the ingathering shall not come.", "acv": "For ye shall be troubled days beyond a year, ye careless women. For the vintage shall fail; the ingathering shall not come.", "anderson": "", "haweis": "", "noyes": "One year more, and ye shall tremble, ye careless women! For the vintage shall fail; the harvest shall not come.", "webster": "Many days and years shall ye be troubled, ye careless women: for the vintage shall fail, the gathering shall not come.", "vulgate": "post dies et annum et vos conturbabimini confidentes consummata est enim vindemia collectio ultra non veniet;", "brenton": "Remember for a full year in pain, yet with hope: the vintage has been cut off; it has ceased, it shall by no means come again."}}, {"v": 11, "ref": "32:11", "o": "חִרְדוּ֙ שַֽׁאֲנַנּ֔וֹת רְגָ֖זָה בֹּֽטְח֑וֹת פְּשֹׁ֣טָֽה וְ/עֹ֔רָה וַ/חֲג֖וֹרָה עַל חֲלָצָֽיִם", "en": {"kjv": "Tremble, ye women that are at ease; be troubled, ye careless ones: strip you, and make you bare, and gird sackcloth upon your loins.", "web": "Tremble, you women who are at ease! Be troubled, you careless ones! Strip yourselves, make yourselves naked, and put sackcloth on your waist.", "bsb": "Shudder, you ladies of leisure; tremble, you daughters of complacency. Strip yourselves bare and put sackcloth around your waists.", "asv": "Tremble, ye women that are at ease; be troubled, ye careless ones; strip you, and make you bare, and gird sackcloth upon your loins.", "ylt": "Tremble ye women, ye easy ones, Be troubled, ye confident ones, Strip and make bare, with a girdle on the loins,", "dra": "Be astonished, ye rich women, be troubled, ye confident ones: strip you, and be confounded, gird your loins.", "bbe": "Be shaking with fear, you women who are living in comfort; be troubled, you who have no fear of danger: take off your robes and put on clothing of grief.", "geneva": "Yee women, that are at ease, be astonied: feare, O yee carelesse women: put off the clothes: make bare, and girde sackcloth vpon the loynes.", "wycliffe": "Ye riche wymmen, be astonyed; ye that tristen, be disturblid; vnclothe ye you, and be ye aschamed;", "rotherham": "Tremble, ye women in comfort, Be troubled ye daughters so confident,—Strip! and bare yourselves, and gird somewhat on your loins:", "darby": "Tremble, ye women that are at ease; be troubled, ye careless ones; strip you, and make you bare, and gird [sackcloth] on your loins!", "twenty": "", "jps": "Tremble, ye women that are at ease; be troubled, ye confident ones; strip you, and make you bare, and gird sackcloth upon your loins,", "acv": "Tremble, ye women who are at ease. Be troubled, ye careless ones. Strip you, and make you bare, and gird sackcloth upon your loins.", "anderson": "", "haweis": "", "noyes": "Tremble, O ye that are at ease! Be in dismay, ye careless ones! Strip you, make you bare, gird ye sackcloth upon your loins!", "webster": "Tremble, ye women that are at ease; be troubled, ye careless ones: strip ye, and make you bare, and gird [sackcloth] upon [your] loins.", "vulgate": "obstupescite opulentae conturbamini confidentes exuite vos et confundimini accingite lumbos vestros;", "brenton": "Be amazed, be pained, ye confident ones: strip you, bare yourselves, gird your loins;"}}, {"v": 12, "ref": "32:12", "o": "עַל שָׁדַ֖יִם סֹֽפְדִ֑ים עַל שְׂדֵי חֶ֕מֶד עַל גֶּ֖פֶן פֹּרִיָּֽה", "en": {"kjv": "They shall lament for the teats, for the pleasant fields, for the fruitful vine.", "web": "Beat your breasts for the pleasant fields, for the fruitful vine.", "bsb": "Beat your breasts for the pleasant fields, for the fruitful vines,", "asv": "They shall smite upon the breasts for the pleasant fields, for the fruitful vine.", "ylt": "For breasts they are lamenting, For fields of desire, for the fruitful vine.", "dra": "Mourn for your breasts, for the delightful country, for the fruitful vineyard.", "bbe": "Have sorrow for the fields, the pleasing fields, the fertile vine;", "geneva": "Men shall lament for the teates, euen for the pleasant fieldes, and for the fruitefull vine.", "wycliffe": "girde youre leendis; weile ye on brestis, on desirable cuntrei, on the plenteuouse vyner.", "rotherham": "Upon your breasts, continue smiting: For desirable fields, For fruitful vine.", "darby": "They shall smite on the breasts [in lamentation] for the pleasant fields, for the fruitful vineyards.", "twenty": "", "jps": "Smiting upon the breasts for the pleasant fields, for the fruitful vine;", "acv": "They shall beat upon the breasts for the pleasant fields, for the fruitful vine.", "anderson": "", "haweis": "", "noyes": "They shall smite themselves on their breasts, On account of the pleasant fields, On account of the fruitful vine.", "webster": "They shall lament for the breasts, for the pleasant fields, for the fruitful vine.", "vulgate": "super ubera plangite super regione desiderabili super vinea fertili;", "brenton": "and beat your breasts, because of the pleasant field, and the fruit of the vine."}}, {"v": 13, "ref": "32:13", "o": "עַ֚ל אַדְמַ֣ת עַמִּ֔/י ק֥וֹץ שָׁמִ֖יר תַּֽעֲלֶ֑ה כִּ֚י עַל כָּל בָּתֵּ֣י מָשׂ֔וֹשׂ קִרְיָ֖ה עַלִּיזָֽה", "en": {"kjv": "Upon the land of my people shall come up thorns and briers; yea, upon all the houses of joy in the joyous city:", "web": "Thorns and briers will come up on my people’s land; yes, on all the houses of joy in the joyous city.", "bsb": "and for the land of my people, overgrown with thorns and briers— even for every house of merriment in this city of revelry.", "asv": "Upon the land of my people shall come up thorns and briers; yea, upon all the houses of joy in the joyous city.", "ylt": "Over the ground of my people thorn--brier goeth up, Surely over all houses of joy of the exulting city,", "dra": "Upon the land of my people shall thorns and briers come up: how much more upon all the houses of joy, of the city that rejoiced?", "bbe": "And for the land of my people, where thorns will come up; even for all the houses of joy in the glad town.", "geneva": "Vpon the lande of my people shall growe thornes and briers: yea, vpon all the houses of ioye in the citie of reioysing,", "wycliffe": "Thornes and breris schulen stie on the erthe of my puple; hou myche more on alle the housis of ioie of the citee makynge ful out ioie?", "rotherham": "Over the soil of my people, thorns and briars shall grow,—Yea over all houses of joy, thou city exultant!", "darby": "Upon the land of my people shall come up thistles [and] briars, yea, upon all the houses of joy in the joyous city.", "twenty": "", "jps": "For the land of my people whereon thorns and briers come up; yea, for all the houses of joy and the joyous city.", "acv": "Thorns and briers shall come up on the land of my people, yea, upon all the houses of joy in the joyous city.", "anderson": "", "haweis": "", "noyes": "Upon the land of my people shall come up thorns and briers; Yea, upon all the houses of joy in the joyous city.", "webster": "Upon the land of my people shall come up thorns [and] briers; also, upon all the houses of joy [in] the joyous city:", "vulgate": "super humum populi mei spina et vepres ascendent quanto magis super omnes domos gaudii civitatis exultantis;", "brenton": "As for the land of my people, the thorn and grass shall come upon it, and joy shall be removed from every house."}}, {"v": 14, "ref": "32:14", "o": "כִּֽי אַרְמ֣וֹן נֻטָּ֔שׁ הֲמ֥וֹן עִ֖יר עֻזָּ֑ב עֹ֣פֶל וָ/בַ֜חַן הָיָ֨ה בְעַ֤ד מְעָרוֹת֙ עַד עוֹלָ֔ם מְשׂ֥וֹשׂ פְּרָאִ֖ים מִרְעֵ֥ה עֲדָרִֽים", "en": {"kjv": "Because the palaces shall be forsaken; the multitude of the city shall be left; the forts and towers shall be for dens for ever, a joy of wild asses, a pasture of flocks;", "web": "For the palace will be forsaken. The populous city will be deserted. The hill and the watchtower will be for dens forever, a delight for wild donkeys, a pasture of flocks;", "bsb": "For the palace will be forsaken, the busy city abandoned. The hill and the watchtower will become caves forever— the delight of wild donkeys and a pasture for flocks—", "asv": "For the palace shall be forsaken; the populous city shall be deserted; the hill and the watch-tower shall be for dens for ever, a joy of wild asses, a pasture of flocks;", "ylt": "Surely the palace hath been left, The multitude of the city forsaken, Fort and watch-tower hath been for dens unto the age, A joy of wild asses--a pasture of herds;", "dra": "For the house is forsaken, the multitude of the city is left, darkness and obscurity are come upon its dens for ever. A joy of wild asses, the pastures of flocks.", "bbe": "For the fair houses will have no man living in them; the town which was full of noise will become a waste; the hill and the watchtower will be unpeopled for ever, a joy for the asses of the woods, a place of food for the flocks;", "geneva": "Because the palace shalbe forsaken, and the noise of the citie shalbe left: the towre and fortresse shalbe dennes for euer, and the delite of wilde asses, and a pasture for flockes,", "wycliffe": "For whi the hous is left, the multitude of the citee is forsakun; derknessis and gropyng ben maad on dennes, `til in to with outen ende. The ioie of wield assis is the lesewe of flockis;", "rotherham": "For the palace, is abandoned, the tumult of the city, hath ceased—Hill and watch-tower, serve as caves, unto times age-abiding, The joy of wild-asses, The pasture of flocks:—", "darby": "For the palace shall be deserted, the multitude of the city shall be forsaken; hill and watchtower shall be caves for ever, a joy of wild asses, a pasture of flocks;", "twenty": "", "jps": "For the palace shall be forsaken; the city with its stir shall be deserted; the mound and the tower shall be for dens for ever, a joy of wild asses, a pasture of flocks;", "acv": "For the palace shall be forsaken. The populous city shall be deserted. The hill and the watch-tower shall be for dens forever, a joy of wild donkeys, a pasture of flocks,", "anderson": "", "haweis": "", "noyes": "For the palace shall be forsaken; The tumult of the city shall be solitary; The fortified hill and the tower shall be dens forever; The joy of wild-asses, the pasture of flocks;", "webster": "Because the palaces shall be forsaken; the multitude of the city shall be left; the forts and towers shall be for dens for ever, a joy of wild asses, a pasture of flocks;", "vulgate": "domus enim dimissa est multitudo urbis relicta est tenebrae et palpatio factae sunt super speluncas usque in aeternum gaudium onagrorum pascua gregum;", "brenton": "As for the rich city, the houses are deserted; they shall abandon the wealth of the city, and the pleasant houses: and the villages shall be caves for ever, the joy of wild asses, shepherds' pastures;"}}, {"v": 15, "ref": "32:15", "o": "עַד יֵ֨עָרֶ֥ה עָלֵ֛י/נוּ ר֖וּחַ מִ/מָּר֑וֹם וְ/הָיָ֤ה מִדְבָּר֙ לַ/כַּרְמֶ֔ל ו/כרמל וְ/הַ/כַּרְמֶ֖ל לַ/יַּ֥עַר יֵחָשֵֽׁב", "en": {"kjv": "Until the spirit be poured upon us from on high, and the wilderness be a fruitful field, and the fruitful field be counted for a forest.", "web": "Until the Spirit is poured on us from on high, and the wilderness becomes a fruitful field, and the fruitful field is considered a forest.", "bsb": "until the Spirit is poured out upon us from on high. Then the desert will be an orchard, and the orchard will seem like a forest.", "asv": "until the Spirit be poured upon us from on high, and the wilderness become a fruitful field, and the fruitful field be esteemed as a forest.", "ylt": "Till emptied out on us is the Spirit from on high, And a wilderness hath become a fruitful field, And the fruitful field for a forest is reckoned.", "dra": "Until the spirit be poured upon us from on high: and the desert shall be as a charmel, and charmel shall be counted for a forest.", "bbe": "Till the spirit comes on us from on high, and the waste land becomes a fertile field, and the fertile field is changed into a wood.", "geneva": "Vntill the Spirit be powred vpon vs from aboue, and the wildernes become a fruitfull fielde, and the plenteous fielde be counted as a forest.", "wycliffe": "til the spirit be sched out on us fro an hiy, and the desert schal be in to Chermel, and Chermel schal be arettid in to a forest.", "rotherham": "Until there be poured out upon us the spirit, from on high,—Then shall the wilderness become, garden-land, And the garden-land, for a forest, be reckoned;", "darby": "until the Spirit be poured upon us from on high, and the wilderness become a fruitful field, and the fruitful field be counted for a forest.", "twenty": "", "jps": "Until the spirit be poured upon us from on high, and the wilderness become a fruitful field, and the fruitful field be counted for a forest.", "acv": "until the Spirit be poured upon us from on high, and the wilderness becomes a fruitful field, and the fruitful field be esteemed as a forest.", "anderson": "", "haweis": "", "noyes": "Until the spirit from on high be poured upon us, And the wilderness become a fruitful field, And the fruitful field be esteemed a forest.", "webster": "Until the spirit shall be poured upon us from on high, and the wilderness shall be a fruitful field, and the fruitful field shall be counted for a forest.", "vulgate": "donec effundatur super nos spiritus de excelso et erit desertum in Chermel et Chermel in saltum reputabitur;", "brenton": "until the Spirit shall come upon you from on high, and Chermel shall be desert, and Chermel shall be counted for a forest."}}, {"v": 16, "ref": "32:16", "o": "וְ/שָׁכַ֥ן בַּ/מִּדְבָּ֖ר מִשְׁפָּ֑ט וּ/צְדָקָ֖ה בַּ/כַּרְמֶ֥ל תֵּשֵֽׁב", "en": {"kjv": "Then judgment shall dwell in the wilderness, and righteousness remain in the fruitful field.", "web": "Then justice will dwell in the wilderness; and righteousness will remain in the fruitful field.", "bsb": "Then justice will inhabit the wilderness, and righteousness will dwell in the fertile field.", "asv": "Then justice shall dwell in the wilderness; and righteousness shall abide in the fruitful field.", "ylt": "And dwelt in the wilderness hath judgment, And righteousness in the fruitful field remaineth.", "dra": "An judgment shall dwell in the wilderness, and justice shall sit in charmel.", "bbe": "Then in the waste land there will be an upright rule, and righteousness will have its place in the fertile field.", "geneva": "And iudgement shall dwel in the desert, and iustice shall remaine in the fruitfull fielde.", "wycliffe": "And doom schal dwelle in wildirnesse, and riytfulnesse schal sitte in Chermel;", "rotherham": "Then shall, justice inhabit, the wilderness, And righteousness, in the garden-land, shall abide;", "darby": "And judgment shall inhabit the wilderness, and righteousness dwell in the fruitful field.", "twenty": "", "jps": "Then justice shall dwell in the wilderness, and righteousness shall abide in the fruitful field.", "acv": "Then justice shall dwell in the wilderness, and righteousness shall abide in the fruitful field.", "anderson": "", "haweis": "", "noyes": "Then shall justice dwell in the wilderness, And righteousness in the fruitful field.", "webster": "Then judgment shall dwell in the wilderness, and righteousness remain in the fruitful field.", "vulgate": "et habitabit in solitudine iudicium et iustitia in Chermel sedebit;", "brenton": "Then judgment shall abide in the wilderness, and righteousness shall dwell in Carmel."}}, {"v": 17, "ref": "32:17", "o": "וְ/הָיָ֛ה מַעֲשֵׂ֥ה הַ/צְּדָקָ֖ה שָׁל֑וֹם וַֽ/עֲבֹדַת֙ הַ/צְּדָקָ֔ה הַשְׁקֵ֥ט וָ/בֶ֖טַח עַד עוֹלָֽם", "en": {"kjv": "And the work of righteousness shall be peace; and the effect of righteousness quietness and assurance for ever.", "web": "The work of righteousness will be peace; and the effect of righteousness, quietness and confidence forever.", "bsb": "The work of righteousness will be peace; the service of righteousness will be quiet confidence forever.", "asv": "And the work of righteousness shall be peace; and the effect of righteousness, quietness and confidence for ever.", "ylt": "And a work of the righteousness hath been peace, And a service of the righteousness--Keeping quiet and confidence unto the age.", "dra": "And the work of justice shall be peace, and the service of justice quietness, and security for ever.", "bbe": "And the work of righteousness will be peace; and the effect of an upright rule will be to take away fear for ever.", "geneva": "And the worke of iustice shall bee peace, euen the worke of iustice and quietnesse, and assurance for euer.", "wycliffe": "and the werk of riytfulnesse schal be pees, and the tilthe of riytfulnesse schal be stilnesse and sikirnesse, `til in to with outen ende.", "rotherham": "And the yield of righteousness, shall be, peace,—And the tillage of righteousness, quietness, and confidence! to times age-abiding;", "darby": "And the work of righteousness shall be peace; and the effect of righteousness, quietness and assurance for ever.", "twenty": "", "jps": "And the work of righteousness shall be peace; and the effect of righteousness quietness and confidence for ever.", "acv": "And the work of righteousness shall be peace, and the effect of righteousness, quietness and confidence forever.", "anderson": "", "haweis": "", "noyes": "And the effect of righteousness shall be peace, And the fruit of righteousness quiet and security forever.", "webster": "And the work of righteousness shall be peace; and the effect of righteousness, quietness and assurance for ever.", "vulgate": "et erit opus iustitiae pax et cultus iustitiae silentium et securitas usque in sempiternum;", "brenton": "And the works of righteousness shall be peace; and righteousness shall ensure rest, and the righteous shall be confident for ever."}}, {"v": 18, "ref": "32:18", "o": "וְ/יָשַׁ֥ב עַמִּ֖/י בִּ/נְוֵ֣ה שָׁל֑וֹם וּֽ/בְ/מִשְׁכְּנוֹת֙ מִבְטַחִ֔ים וּ/בִ/מְנוּחֹ֖ת שַׁאֲנַנּֽוֹת", "en": {"kjv": "And my people shall dwell in a peaceable habitation, and in sure dwellings, and in quiet resting places;", "web": "My people will live in a peaceful habitation, in safe dwellings, and in quiet resting places.", "bsb": "Then my people will dwell in a peaceful place, in safe and secure places of rest.", "asv": "And my people shall abide in a peaceable habitation, and in safe dwellings, and in quiet resting-places.", "ylt": "And dwelt hath My people in a peaceful habitation, And in stedfast tabernacles, And in quiet resting-places.", "dra": "And my people shall sit in the beauty of peace, and in the tabernacles of confidence, and in wealthy rest.", "bbe": "And my people will be living in peace, in houses where there is no fear, and in quiet resting-places.", "geneva": "And my people shall dwell in the tabernacle of peace, and in sure dwellings, and in safe resting places.", "wycliffe": "And my puple schal sitte in the fairnesse of pees, and in the tabernaclis of trist, and in riche reste.", "rotherham": "And my people shall dwell, In a borne of peace,—and In habitations of security, and In resting-places of comfort.", "darby": "And my people shall dwell in a peaceable habitation, and in sure dwellings, and in quiet resting-places.", "twenty": "", "jps": "And my people shall abide in a peaceable habitation, and in secure dwellings, and in quiet resting-places.", "acv": "And my people shall abide in a peaceable habitation, and in safe dwellings, and in quiet resting-places.", "anderson": "", "haweis": "", "noyes": "Then shall my people dwell in peaceful habitations, In secure dwellings, in quiet resting-places.", "webster": "And my people shall dwell in a peaceable habitation, and in sure dwellings, and in quiet resting-places;", "vulgate": "et sedebit populus meus in pulchritudine pacis et in tabernaculis fiduciae et in requie opulenta;", "brenton": "And his people shall inhabit a city of peace, and dwell in it in confidence, and they shall rest with wealth."}}, {"v": 19, "ref": "32:19", "o": "וּ/בָרַ֖ד בְּ/רֶ֣דֶת הַ/יָּ֑עַר וּ/בַ/שִּׁפְלָ֖ה תִּשְׁפַּ֥ל הָ/עִֽיר", "en": {"kjv": "When it shall hail, coming down on the forest; and the city shall be low in a low place.", "web": "Though hail flattens the forest, and the city is leveled completely.", "bsb": "But hail will level the forest, and the city will sink to the depths.", "asv": "But it shall hail in the downfall of the forest; and the city shall be utterly laid low.", "ylt": "And it hath hailed in the going down of the forest, And in the valley is the city low.", "dra": "But hail shall be in the descent of the forest, and the city shall be made very low.", "bbe": "But the tall trees will come down with a great fall, and the town will be low in a low place.", "geneva": "When it haileth, it shall fall on the forest, and the citie shall be set in the lowe place.", "wycliffe": "But hail schal be in the coming doun of the foreste, and bi lownesse the citee schal be maad low.", "rotherham": "But it shall hail during the felling of the forest, And in a sunken place, shall, the city, sink.", "darby": "And it shall hail, coming down on the forest; and the city shall be low in a low place.", "twenty": "", "jps": "And it shall hail, in the downfall of the forest; but the city shall descend into the valley.", "acv": "But it shall hail in the downfall of the forest, and the city shall be utterly laid low.", "anderson": "", "haweis": "", "noyes": "But the hail shall descend, and the forest shall fall; And the city shall be brought very low.", "webster": "When it shall hail, coming down on the forest; and the city shall be low in a low place.", "vulgate": "grando autem in descensione saltus et humilitate humiliabitur civitas;", "brenton": "And if the hail should come down, it shall not come upon you; and they that dwell in the forests shall be in confidence, as those in the plain country."}}, {"v": 20, "ref": "32:20", "o": "אַשְׁרֵי/כֶ֕ם זֹרְעֵ֖י עַל כָּל מָ֑יִם מְשַׁלְּחֵ֥י רֶֽגֶל הַ/שּׁ֖וֹר וְ/הַ/חֲמֽוֹר", "en": {"kjv": "Blessed are ye that sow beside all waters, that send forth thither the feet of the ox and the ass.", "web": "Blessed are you who sow beside all waters, who send out the feet of the ox and the donkey.", "bsb": "Blessed are those who sow beside abundant waters, who let the ox and donkey range freely.", "asv": "Blessed are ye that sow beside all waters, that send forth the feet of the ox and the ass.", "ylt": "Happy are ye sowing by all waters, Sending forth the foot of the ox and the ass!", "dra": "Blessed are ye that sow upon all waters, sending thither the foot of the ox and the ass.", "bbe": "Happy are you who are planting seed by all the waters, and sending out the ox and the ass.", "geneva": "Blessed are ye that sowe vpon all waters, and driue thither the feete of the oxe and the asse.", "wycliffe": "Blessid ben ye, that sowen on alle watris, and putten yn the foot of an oxe and of an asse.", "rotherham": "How happy are ye who sow beside all waters,—Who send forth the foot of the ox and the ass.", "darby": "Blessed are ye that sow beside all waters, that send forth the feet of the ox and the ass.", "twenty": "", "jps": "Happy are ye that sow beside all waters, that send forth freely the feet of the ox and the ass.", "acv": "Blessed are ye who sow beside all waters, who send forth the feet of the ox and the donkey.", "anderson": "", "haweis": "", "noyes": "Happy ye who sow beside all waters; Who send forth thither the feet of the ox and the ass!", "webster": "Blessed [are] ye that sow beside all waters, that send forth [thither] the feet of the ox and the ass.", "vulgate": "beati qui seminatis super omnes aquas inmittentes pedem bovis et asini;", "brenton": "Blessed are they that sow by every water, where the ox and ass tread."}}]}, {"c": 33, "verses": [{"v": 1, "ref": "33:1", "o": "ה֣וֹי שׁוֹדֵ֗ד וְ/אַתָּה֙ לֹ֣א שָׁד֔וּד וּ/בוֹגֵ֖ד וְ/לֹא בָ֣גְדוּ ב֑/וֹ כַּ/הֲתִֽמְ/ךָ֤ שׁוֹדֵד֙ תּוּשַּׁ֔ד כַּ/נְּלֹתְ/ךָ֥ לִ/בְגֹּ֖ד יִבְגְּדוּ בָֽ/ךְ", "en": {"kjv": "Woe to thee that spoilest, and thou wast not spoiled; and dealest treacherously, and they dealt not treacherously with thee! when thou shalt cease to spoil, thou shalt be spoiled; and when thou shalt make an end to deal treacherously, they shall deal treacherously with thee.", "web": "Woe to you who destroy, but you weren’t destroyed; and who betray, but nobody betrayed you! When you have finished destroying, you will be destroyed; and when you have made an end of betrayal, you will be betrayed.", "bsb": "Woe to you, O destroyer never destroyed, O traitor never betrayed! When you have finished destroying, you will be destroyed. When you have finished betraying, you will be betrayed.", "asv": "Woe to thee that destroyest, and thou wast not destroyed; and dealest treacherously, and they dealt not treacherously with thee! When thou hast ceased to destroy, thou shalt be destroyed; and when thou hast made an end of dealing treacherously, they shall deal treacherously with thee.", "ylt": "Woe, spoiler! and thou not spoiled, And treacherous! and they dealt not treacherously with thee, When thou dost finish, O spoiler, thou art spoiled, When thou dost finish dealing treacherously, They deal treacherously with thee.", "dra": "Woe to thee that spoilest, shalt not thou thyself also be spoiled? and thou that despisest, shalt not thyself also be despised? when thou shalt have made an end of spoiling, thou shalt be spoiled: when being wearied thou shalt cease to despise, thou shalt be despised.", "bbe": "Ho! you who make waste those who did not make you waste; acting falsely to those who were not false to you. When you have come to an end of wasting, you will be made waste, and after your false acts, they will do the same to you.", "geneva": "Woe to thee that spoylest, and wast not spoyled: and doest wickedly, and they did not wickedly against thee: when thou shalt cease to spoyle, thou shalt be spoyled: when thou shalt make an ende of doing wickedly, they shall doe wickedly against thee.", "wycliffe": "Wo to thee, that robbest; whether and thou schalt not be robbid? and that dispisist, whether and thou schalt not be dispisid? Whanne thou hast endid robbyng, thou schalt be robbid; and whanne thou maad weri ceessist to dispise, thou schalt be dispisid.", "rotherham": "Alas! thou plunderer when, thou, hadst not been plundered, And thou traitor when they had not betrayed thee: When thou hast ceased plundering, thou shalt be plundered, When thou hast left off betraying, they shall betray thee.", "darby": "Woe to thee that spoilest, and thou wast not spoiled; and that dealest treacherously, and they dealt not treacherously with thee! When thou shalt cease to spoil, thou shalt be spoiled; when thou shalt make an end of dealing treacherously, they shall deal treacherously with thee.", "twenty": "", "jps": "Woe to thee that spoilest, and thou wast not spoiled; and dealest treacherously, and they dealt not treacherously with thee! When thou hast ceased to spoil, thou shalt be spoiled; and when thou art weary with dealing treacherously, they shall deal treacherously with thee.", "acv": "Woe to thee who destroys, and thou were not destroyed, and deal treacherously, and they did not deal treacherously with thee! When thou have ceased to destroy, thou shall be destroyed, and when thou have made an end of dealing treacherously, they shall deal treacherously with thee.", "anderson": "", "haweis": "", "noyes": "Woe to thee, thou spoiler, who hast not been spoiled! Thou plunderer, who hast not been plundered! When thou hast ceased to spoil, thou shalt be spoiled; When thou hast finished plundering, they shall plunder thee.", "webster": "Woe to thee that layest waste, and thou [wast] not laid waste; and dealest treacherously, and they dealt not treacherously with thee! when thou shalt cease to lay waste, thou shalt be wasted; [and] when thou shalt make an end to deal treacherously, they shall deal treacherously with thee.", "vulgate": "vae qui praedaris nonne et ipse praedaberis et qui spernis nonne et ipse sperneris cum consummaveris depraedationem depraedaberis cum fatigatus desiveris contemnere contemneris;", "brenton": "Woe to them that afflict you; but no one makes you miserable: and he that deals perfidiously with you does not deal perfidiously: they that deal perfidiously shall be taken and given up, and as a moth on a garment, so shall they be spoiled."}}, {"v": 2, "ref": "33:2", "o": "יְהוָ֥ה חָנֵּ֖/נוּ לְ/ךָ֣ קִוִּ֑ינוּ הֱיֵ֤ה זְרֹעָ/ם֙ לַ/בְּקָרִ֔ים אַף יְשׁוּעָתֵ֖/נוּ בְּ/עֵ֥ת צָרָֽה", "en": {"kjv": "O Lord, be gracious unto us; we have waited for thee: be thou their arm every morning, our salvation also in the time of trouble.", "web": "Yahweh, be gracious to us. We have waited for you. Be our strength every morning, our salvation also in the time of trouble.", "bsb": "O LORD, be gracious to us! We wait for You. Be our strength every morning and our salvation in time of trouble.", "asv": "O Jehovah, be gracious unto us; we have waited for thee: be thou our arm every morning, our salvation also in the time of trouble.", "ylt": "O Jehovah, favour us, for thee we have waited, Be their arm, in the mornings, Yea, our salvation in time of adversity.", "dra": "O Lord, have mercy on us: for we have waited for thee: be thou our arm in the morning, and our salvation in the time of trouble.", "bbe": "O Lord, have mercy on us; for we have been waiting for your help: be our strength every morning, our salvation in time of trouble.", "geneva": "O Lord, haue mercie vpon vs, wee haue waited for thee: be thou, which waste their arme in the morning, our helpe also in time of trouble.", "wycliffe": "Lord, haue thou merci on vs, for we abiden thee; be thou oure arm in the morewtid, and oure helthe in the tyme of tribulacioun.", "rotherham": "O Yahweh! shew us favour,—For thee, have we waited,—Be thou their arm every morning, Yea our salvation in the time of distress.", "darby": "Jehovah, be gracious unto us; we have waited for thee: be their arm every morning, yea, our salvation in the time of trouble.", "twenty": "", "jps": "O HaShem, be gracious unto us; we have waited for Thee; be Thou their arm every morning, our salvation also in the time of trouble.", "acv": "O Jehovah, be gracious to us, we have waited for thee. Be thou our arm every morning, also our salvation in the time of trouble.", "anderson": "", "haweis": "", "noyes": "O Jehovah, have mercy upon us! in thee do we trust; Be thou our strength every morning, Our salvation in the time of trouble.", "webster": "O LORD, be gracious to us; we have waited for thee: be thou their arm every morning, our salvation also in the time of trouble.", "vulgate": "Domine miserere nostri te expectavimus esto brachium eorum in mane et salus nostra in tempore tribulationis;", "brenton": "Lord, have mercy upon us; for we have trusted in thee: the seed of the rebellious is gone to destruction, but our deliverance was in a time of affliction."}}, {"v": 3, "ref": "33:3", "o": "מִ/קּ֣וֹל הָמ֔וֹן נָדְד֖וּ עַמִּ֑ים מֵ/ר֣וֹמְמֻתֶ֔/ךָ נָפְצ֖וּ גּוֹיִֽם", "en": {"kjv": "At the noise of the tumult the people fled; at the lifting up of thyself the nations were scattered.", "web": "At the noise of the thunder, the peoples have fled. When you lift yourself up, the nations are scattered.", "bsb": "The peoples flee the thunder of Your voice; the nations scatter when You rise.", "asv": "At the noise of the tumult the peoples are fled; at the lifting up of thyself the nations are scattered.", "ylt": "From the voice of a multitude fled have peoples, From thine exaltation scattered have been nations.", "dra": "At the voice of the angel the people fled, and at the lifting up thyself the nations are scattered.", "bbe": "At the loud noise the peoples have gone in flight; at your coming up the nations have gone in all directions.", "geneva": "At the noise of the tumult, the people fled: at thine exalting the nations were scattered.", "wycliffe": "Puplis fledden fro the vois of the aungel; hethene men ben scaterid of thin enhaunsyng.", "rotherham": "At the noise of a tumult, the peoples retreated,—When thou didst lift thyself up, nations were scattered.", "darby": "At the noise of the tumult the peoples fled; at the lifting up of thyself the nations were scattered.", "twenty": "", "jps": "At the noise of the tumult the peoples are fled; at the lifting up of Thyself the nations are scattered.", "acv": "At the noise of the tumult the peoples have fled. At the lifting up of thyself the nations are scattered.", "anderson": "", "haweis": "", "noyes": "At the voice of thy thunder the people flee; When thou dost arise, the nations are scattered.", "webster": "At the noise of the tumult the people fled; at the lifting up of thyself the nations were scattered.", "vulgate": "a voce angeli fugerunt populi ab exaltatione tua dispersae sunt gentes;", "brenton": "By reason of the terrible sound the nations were dismayed for fear of thee, and the heathen were scattered."}}, {"v": 4, "ref": "33:4", "o": "וְ/אֻסַּ֣ף שְׁלַלְ/כֶ֔ם אֹ֖סֶף הֶֽ/חָסִ֑יל כְּ/מַשַּׁ֥ק גֵּבִ֖ים שׁוֹקֵ֥ק בּֽ/וֹ", "en": {"kjv": "And your spoil shall be gathered like the gathering of the caterpiller: as the running to and fro of locusts shall he run upon them.", "web": "Your plunder will be gathered as the caterpillar gathers. Men will leap on it as locusts leap.", "bsb": "Your spoil, O nations, is gathered as by locusts; like a swarm of locusts men sweep over it.", "asv": "And your spoil shall be gathered as the caterpillar gathereth: as locusts leap shall men leap upon it.", "ylt": "And gathered hath been your spoil, A gathering of the caterpillar, As a running to and fro of locusts is he running on it.", "dra": "And your spoils shall be gathered together as the locusts are gathered, as when the ditches are full of them.", "bbe": "And the goods taken in war will be got together like the massing of young locusts; men will be rushing on them like the rushing of locusts.", "geneva": "And your spoyle shall be gathered like the gathering of caterpillers: and he shall go against him like the leaping of grashoppers.", "wycliffe": "And youre spuylis schulen be gaderid togidere, as a bruke is gaderid togidere, as whanne dichis ben ful therof.", "rotherham": "Then shall your spoil be gathered as the gathering of the caterpillar,—As the swift running of locusts, is he about to run upon them.", "darby": "And your spoil shall be gathered [like] the gathering of the caterpillar: as the running of locusts shall they run upon it.", "twenty": "", "jps": "And your spoil is gathered as the caterpillar gathereth; as locusts leap do they leap upon it.", "acv": "And your spoil shall be gathered as the caterpillar gathers. As locusts leap, men shall leap upon it.", "anderson": "", "haweis": "", "noyes": "Your spoil shall be gathered, as the locust gathereth; As the locust runneth, so shall they run upon it.", "webster": "And your spoil shall be gathered [like] the gathering of the caterpillar: as the running to and fro of locusts shall he run upon them.", "vulgate": "et congregabuntur spolia vestra sicut colligitur brucus velut cum fossae plenae fuerint de eo;", "brenton": "And now shall the spoils of your small and great be gathered: as if one should gather locusts, so shall they mock you."}}, {"v": 5, "ref": "33:5", "o": "נִשְׂגָּ֣ב יְהוָ֔ה כִּ֥י שֹׁכֵ֖ן מָר֑וֹם מִלֵּ֣א צִיּ֔וֹן מִשְׁפָּ֖ט וּ/צְדָקָֽה", "en": {"kjv": "The Lord is exalted; for he dwelleth on high: he hath filled Zion with judgment and righteousness.", "web": "Yahweh is exalted, for he dwells on high. He has filled Zion with justice and righteousness.", "bsb": "The LORD is exalted, for He dwells on high; He has filled Zion with justice and righteousness.", "asv": "Jehovah is exalted; for he dwelleth on high: he hath filled Zion with justice and righteousness.", "ylt": "Set on high is Jehovah, for He is dwelling on high, He filled Zion with judgment and righteousness,", "dra": "The Lord is magnified, for he hath dwelt on high: he hath filled Sion with judgment and justice.", "bbe": "The Lord is lifted up; his place is on high: he has made Zion full of righteousness and true religion.", "geneva": "The Lord is exalted: for hee dwelleth on hie: he hath filled Zion with iudgement and iustice.", "wycliffe": "The Lord is magnefied, for he dwellide an hiy, he fillid Sion with doom and riytfulnesse.", "rotherham": "Exalted is Yahweh, for he inhabiteth a height,—He hath filled Zion with justice and righteousness.", "darby": "Jehovah is exalted; for he dwelleth on high: he hath filled Zion with justice and righteousness;", "twenty": "", "jps": "HaShem is exalted, for He dwelleth on high; He hath filled Zion with justice and righteousness.", "acv": "Jehovah is exalted, for he dwells on high. He has filled Zion with justice and righteousness.", "anderson": "", "haweis": "", "noyes": "Jehovah is exalted; Yea, he dwelleth on high; He filleth Zion with justice and righteousness.", "webster": "The LORD is exalted; for he dwelleth on high: he hath filled Zion with judgment and righteousness.", "vulgate": "magnificatus est Dominus quoniam habitavit in excelso implevit Sion iudicio et iustitia;", "brenton": "The God who dwells on high is holy: Sion is filled with judgment and righteousness."}}, {"v": 6, "ref": "33:6", "o": "וְ/הָיָה֙ אֱמוּנַ֣ת עִתֶּ֔י/ךָ חֹ֥סֶן יְשׁוּעֹ֖ת חָכְמַ֣ת וָ/דָ֑עַת יִרְאַ֥ת יְהוָ֖ה הִ֥יא אוֹצָרֽ/וֹ", "en": {"kjv": "And wisdom and knowledge shall be the stability of thy times, and strength of salvation: the fear of the Lord is his treasure.", "web": "There will be stability in your times, abundance of salvation, wisdom, and knowledge. The fear of Yahweh is your treasure.", "bsb": "He will be the sure foundation for your times, a storehouse of salvation, wisdom, and knowledge. The fear of the LORD is Zion’s treasure.", "asv": "And there shall be stability in thy times, abundance of salvation, wisdom, and knowledge: the fear of Jehovah is thy treasure.", "ylt": "And hath been the stedfastness of thy times, The strength of salvation, wisdom, and knowledge, Fear of Jehovah--it is His treasure.", "dra": "And there shall be faith in thy times: riches of salvation, wisdom and knowledge: the fear of the Lord is his treasure.", "bbe": "And she will have no more fear of change, being full of salvation, wisdom, and knowledge: the fear of the Lord is her wealth.", "geneva": "And there shall be stabilitie of thy times, strength, saluation, wisdome and knowledge: for the feare of the Lord shalbe his treasure.", "wycliffe": "And feith schal be in thi tymes; the ritchessis of helthe is wisdom and kunnynge; the drede of the Lord, thilke is the tresour of hym.", "rotherham": "So shall a wealth of deliverances, wisdom and knowledge, become the stability of thy times,—the reverence of Yahweh, the same is his treasure.", "darby": "and he shall be the stability of thy times, the riches of salvation, wisdom and knowledge: the fear of Jehovah shall be your treasure.", "twenty": "", "jps": "And the stability of thy times shall be a hoard of salvation--wisdom and knowledge, and the fear of HaShem which is His treasurer", "acv": "And there shall be stability in thy times, abundance of salvation, wisdom, and knowledge. The fear of Jehovah is thy treasure.", "anderson": "", "haweis": "", "noyes": "There shall be security in thy times; Wisdom and knowledge shall be thy store of prosperity, And the fear of Jehovah, this shall be thy treasure!", "webster": "And wisdom and knowledge shall be the stability of thy times, [and] strength of salvation: the fear of the LORD [is] his treasure.", "vulgate": "et erit fides in temporibus tuis divitiae salutis sapientia et scientia timor Domini ipse thesaurus eius;", "brenton": "They shall be delivered up to the law: our salvation is our treasure: there are wisdom and knowledge and piety toward the Lord; these are the treasures of righteousness."}}, {"v": 7, "ref": "33:7", "o": "הֵ֚ן אֶרְאֶלָּ֔ם צָעֲק֖וּ חֻ֑צָ/ה מַלְאֲכֵ֣י שָׁל֔וֹם מַ֖ר יִבְכָּיֽוּ/ן", "en": {"kjv": "Behold, their valiant ones shall cry without: the ambassadors of peace shall weep bitterly.", "web": "Behold, their valiant ones cry outside; the ambassadors of peace weep bitterly.", "bsb": "Behold, their valiant ones cry aloud in the streets; the envoys of peace weep bitterly.", "asv": "Behold, their valiant ones cry without; the ambassadors of peace weep bitterly.", "ylt": "Lo, `Their Ariel,' they have cried without, Messengers of peace do weep bitterly.", "dra": "Behold they that see shall cry without, the angels of peace shall weep bitterly.", "bbe": "See, the men of war are sorrowing outside the town: those who came looking for peace are weeping bitterly.", "geneva": "Behold, their messengers shall cry without, and ye ambassadours of peace shall weepe bitterly.", "wycliffe": "Lo! seeris withoutenforth schulen crye, aungels of pees schulen wepe bittirli.", "rotherham": "Lo! their heroes, have cried out openly,—the messengers of peace, in bitterness, continue weeping [they say] :", "darby": "Behold, their valiant ones cry without; the messengers of peace weep bitterly.", "twenty": "", "jps": "Behold, their valiant ones cry without; the ambassadors of peace weep bitterly.", "acv": "Behold, their valiant ones cry outside. The ambassadors of peace weep bitterly.", "anderson": "", "haweis": "", "noyes": "Behold, the mighty men cry without: The ambassadors of peace weep bitterly.", "webster": "Behold, their valiant ones shall cry without: the embassadors of peace shall weep bitterly.", "vulgate": "ecce videntes clamabunt foris angeli pacis amare flebunt;", "brenton": "Behold now, these shall be terrified with fear of you: those whom ye feared shall cry out because of you: messengers shall be sent, bitterly weeping, entreating for peace."}}, {"v": 8, "ref": "33:8", "o": "נָשַׁ֣מּוּ מְסִלּ֔וֹת שָׁבַ֖ת עֹבֵ֣ר אֹ֑רַח הֵפֵ֤ר בְּרִית֙ מָאַ֣ס עָרִ֔ים לֹ֥א חָשַׁ֖ב אֱנֽוֹשׁ", "en": {"kjv": "The highways lie waste, the wayfaring man ceaseth: he hath broken the covenant, he hath despised the cities, he regardeth no man.", "web": "The highways are desolate. The traveling man ceases. The covenant is broken. He has despised the cities. He doesn’t respect man.", "bsb": "The highways are deserted; travel has ceased. The treaty has been broken, the witnesses are despised, and human life is disregarded.", "asv": "The highways lie waste, the wayfaring man ceaseth: the enemy hath broken the covenant, he hath despised the cities, he regardeth not man.", "ylt": "Desolated have been highways, Ceased hath he who passeth along the path, He hath broken covenant, He hath despised enemies, He hath not esteemed a man.", "dra": "The ways are made desolate, no one passeth by the road, the covenant is made void, he hath rejected the cities, he hath not regarded the men.", "bbe": "The highways are waste, no man is journeying there: the agreement is broken, he has made sport of the towns, he has no thought for man.", "geneva": "The pathes are waste: the wayfaring man ceaseth: hee hath broken the couenant: hee hath contemned the cities: he regarded no man.", "wycliffe": "Weies ben distried, a goere bi the path ceesside; the couenaunt is maad voide, he castide doun citees, he arettide not men.", "rotherham": "The highways are deserted, The passer-by on the path, hath ceased,—He hath broken covenant, He hath despised cities, He hath made no account of men.", "darby": "The highways are desolate, the wayfaring man ceaseth. He hath broken the covenant, he hath despised the cities, he regardeth no man.", "twenty": "", "jps": "The highways lie waste, the wayfaring man ceaseth; he hath broken the covenant, he hath despised the cities, he regardeth not man.", "acv": "The highways lie waste. The wayfaring man ceases. The enemy has broken the covenant. He has despised the cities. He does not regard man.", "anderson": "", "haweis": "", "noyes": "The highways are desolate; The traveller ceaseth; He breaketh the covenant; he despiseth the cities; Of men he maketh no account.", "webster": "The highways lie waste, the way-faring man ceaseth: he hath broken the covenant, he hath despised the cities, he regardeth no man.", "vulgate": "dissipatae sunt viae cessavit transiens per semitam irritum factum est pactum proiecit civitates non reputavit homines;", "brenton": "For the ways of these shall be made desolate: the terror of the nations has been made to cease, and the covenant with these is taken away, and ye shall by no means deem them men."}}, {"v": 9, "ref": "33:9", "o": "אָבַ֤ל אֻמְלְלָה֙ אָ֔רֶץ הֶחְפִּ֥יר לְבָנ֖וֹן קָמַ֑ל הָיָ֤ה הַ/שָּׁרוֹן֙ כָּֽ/עֲרָבָ֔ה וְ/נֹעֵ֥ר בָּשָׁ֖ן וְ/כַרְמֶֽל", "en": {"kjv": "The earth mourneth and languisheth: Lebanon is ashamed and hewn down: Sharon is like a wilderness; and Bashan and Carmel shake off their fruits.", "web": "The land mourns and languishes. Lebanon is confounded and withers away. Sharon is like a desert, and Bashan and Carmel are stripped bare.", "bsb": "The land mourns and languishes; Lebanon is ashamed and decayed. Sharon is like a desert; Bashan and Carmel shake off their leaves.", "asv": "The land mourneth and languisheth; Lebanon is confounded and withereth away; Sharon is like a desert; and Bashan and Carmel shake off their leaves.", "ylt": "Mourned, languished hath the land, Confounded hath been Lebanon, Withered hath been Sharon as a wilderness, And shaking are Bashan and Carmel.", "dra": "The land hath mourned, and languished: Libanus is confounded, and become foul, and Saron is become as a desert: and Basan and Carmel are shaken.", "bbe": "The earth is sorrowing and wasting away; Lebanon is put to shame and has become waste; Sharon is like the Arabah; and in Bashan and Carmel the leaves are falling.", "geneva": "The earth mourneth and fainteth: Lebanon is ashamed, and hewen downe: Sharon is like a wildernes, and Bashan is shaken and Carmel.", "wycliffe": "The lond morenyde, and was sijk; the Liban was schent, and was foul; and Saron is maad as desert, and Basan is schakun, and Carmele.", "rotherham": "The land mourneth, languisheth, Lebanon, displayeth shame, is withered,—Sharon, hath become, as the waste plain, And Bashan and Carmel are shaking off their leaves.", "darby": "The land mourneth, it languisheth; Lebanon is ashamed, is withered; the Sharon is become as a desert, and Bashan and Carmel are stripped.", "twenty": "", "jps": "The land mourneth and languisheth; Lebanon is ashamed, it withereth; Sharon is like a wilderness; and Bashan and Carmel are clean bare.", "acv": "The land mourns and languishes. Lebanon is confounded and withers away. Sharon is like a desert, and Bashan and Carmel shake off their leaves.", "anderson": "", "haweis": "", "noyes": "The land mourneth and languisheth; Lebanon is put to shame, and withered away; Sharon is like a desert, And Bashan and Carmel are stripped of their leaves.", "webster": "The earth mourneth [and] languisheth: Lebanon is ashamed [and] hewn down: Sharon is like a wilderness; and Bashan and Carmel shake off [their fruits].", "vulgate": "luxit et elanguit terra confusus est Libanus et obsorduit et factus est Saron sicut desertum et concussa est Basan et Carmelus;", "brenton": "The land mourns; Libanus is ashamed: Saron is become marshes; Galilee shall be laid bare, and Chermel."}}, {"v": 10, "ref": "33:10", "o": "עַתָּ֥ה אָק֖וּם יֹאמַ֣ר יְהוָ֑ה עַתָּה֙ אֵֽרוֹמָ֔ם עַתָּ֖ה אֶנָּשֵֽׂא", "en": {"kjv": "Now will I rise, saith the Lord; now will I be exalted; now will I lift up myself.", "web": "“Now I will arise,” says Yahweh; “Now I will lift myself up. Now I will be exalted.", "bsb": "“Now I will arise,” says the LORD. “Now I will lift Myself up. Now I will be exalted.", "asv": "Now will I arise, saith Jehovah; now will I lift up myself; now will I be exalted.", "ylt": "Now, do I arise, saith Jehovah, Now I am exalted, now I am lifted up.", "dra": "Now will I rise up, saith the Lord: now will I be exalted, now will I lift up myself.", "bbe": "Now will I come forward, says the Lord; now will I be lifted up; now will my power be seen.", "geneva": "Now will I arise, saith the Lord: now will I be exalted, now will I lift vp my selfe.", "wycliffe": "Now Y schal ryse, seith the Lord, now I schal be enhaunsid, and now I schal be reisid vp.", "rotherham": "Now, will I arise, Saith Yahweh, Now, will I lift myself up, Now, will I be exalted!", "darby": "Now will I arise, saith Jehovah; now will I be exalted, now will I lift up myself.", "twenty": "", "jps": "Now will I arise, saith HaShem; now will I be exalted; now will I lift Myself up.", "acv": "Now I will arise, says Jehovah. Now I will lift up myself. Now I will be exalted.", "anderson": "", "haweis": "", "noyes": "Now will I arise, saith Jehovah, Now will I exalt myself, Now will I lift myself up.", "webster": "Now will I rise, saith the LORD; now will I be exalted; now will I lift up myself.", "vulgate": "nunc consurgam dicit Dominus nunc exaltabor nunc sublevabor;", "brenton": "Now will I arise, saith the Lord, now will I be glorified; now will I be exalted."}}, {"v": 11, "ref": "33:11", "o": "תַּהֲר֥וּ חֲשַׁ֖שׁ תֵּ֣לְדוּ קַ֑שׁ רוּחֲ/כֶ֕ם אֵ֖שׁ תֹּאכַלְ/כֶֽם", "en": {"kjv": "Ye shall conceive chaff, ye shall bring forth stubble: your breath, as fire, shall devour you.", "web": "You will conceive chaff. You will give birth to stubble. Your breath is a fire that will devour you.", "bsb": "You conceive chaff; you give birth to stubble. Your breath is a fire that will consume you.", "asv": "Ye shall conceive chaff, ye shall bring forth stubble: your breath is a fire that shall devour you.", "ylt": "Ye conceive chaff, ye bear stubble, Your spirit! --fire devoureth you.", "dra": "You shall conceive heat, you shall bring forth stubble: your breath as fire shall devour you.", "bbe": "Your designs will be without profit, and their effect will be nothing: you will be burned up by the fire of my breath.", "geneva": "Ye shall conceiue chaffe, and bring forth stubble: the fire of your breath shall deuoure you.", "wycliffe": "Ye schulen conseyue heete, ye schulen brynge forth stobil; youre spirit as fier schal deuoure you.", "rotherham": "Ye shall conceive chaff Ye shall bring forth stubble,—Your own breath, like fire, shall devour you.", "darby": "Ye shall conceive dry grass, ye shall bring forth stubble: your breath shall devour you [as] fire.", "twenty": "", "jps": "Ye conceive chaff, ye shall bring forth stubble; your breath is a fire that shall devour you.", "acv": "Ye shall conceive chaff. Ye shall bring forth stubble. Your breath is a fire that shall devour you.", "anderson": "", "haweis": "", "noyes": "Ye shall conceive chaff, and bring forth stubble; Your own wrath is the fire which shall devour you.", "webster": "Ye shall conceive chaff, ye shall bring forth stubble: your breath, [as] fire, shall devour you.", "vulgate": "concipietis ardorem parietis stipulam spiritus vester ut ignis vorabit vos;", "brenton": "Now shall ye see, now shall ye perceive; the strength of your breath, shall be vain; fire shall devour you."}}, {"v": 12, "ref": "33:12", "o": "וְ/הָי֥וּ עַמִּ֖ים מִשְׂרְפ֣וֹת שִׂ֑יד קוֹצִ֥ים כְּסוּחִ֖ים בָּ/אֵ֥שׁ יִצַּֽתּוּ", "en": {"kjv": "And the people shall be as the burnings of lime: as thorns cut up shall they be burned in the fire.", "web": "The peoples will be like the burning of lime, like thorns that are cut down and burned in the fire.", "bsb": "The peoples will be burned to ashes, like thorns cut down and set ablaze.", "asv": "And the peoples shall be as the burnings of lime, as thorns cut down, that are burned in the fire.", "ylt": "And peoples have been as burnings of lime, Thorns, as sweepings, with fire they burn.", "dra": "And the people shall be as ashes after a fire, as a bundle of thorns they shall be burnt with fire.", "bbe": "And the peoples will be like the burning of chalk: as thorns cut down, which are burned in the fire.", "geneva": "And the people shall be as the burning of lime: and as the thornes cut vp, shall they be burnt in the fire.", "wycliffe": "And puplis schulen be as aischis of the brennyng; thornes gaderid togidere schulen be brent in fier.", "rotherham": "So shall peoples, become, as the burnings of lime,—As thorns lopped off, with fire, shall they be burned.", "darby": "And the peoples shall be [as] burnings of lime, [as] thorns cut up shall they be burned in the fire.", "twenty": "", "jps": "And the peoples shall be as the burnings of lime; as thorns cut down, that are burned in the fire.", "acv": "And the peoples shall be as the burnings of lime, as thorns cut down that are burned in the fire.", "anderson": "", "haweis": "", "noyes": "The nations shall be burnt into lime; Like thorns cut down, they shall be consumed with fire.", "webster": "And the people shall be [as] the burnings of lime: [as] thorns cut up shall they be burned in the fire.", "vulgate": "et erunt populi quasi de incendio cinis spinae congregatae igni conburentur;", "brenton": "And the nations shall be burnt up; as a thorn in the field cast out and burnt up."}}, {"v": 13, "ref": "33:13", "o": "שִׁמְע֥וּ רְחוֹקִ֖ים אֲשֶׁ֣ר עָשִׂ֑יתִי וּ/דְע֥וּ קְרוֹבִ֖ים גְּבֻרָתִֽ/י", "en": {"kjv": "Hear, ye that are far off, what I have done; and, ye that are near, acknowledge my might.", "web": "Hear, you who are far off, what I have done; and, you who are near, acknowledge my might.”", "bsb": "You who are far off, hear what I have done; you who are near, acknowledge My might.”", "asv": "Hear, ye that are far off, what I have done; and, ye that are near, acknowledge my might.", "ylt": "Hear, ye far off, that which I have done, And know, ye near ones, My might.", "dra": "Hear, you that are far off, what I have done, and you that are near know my strength.", "bbe": "Give ear, you who are far off, to what I have done: see my power, you who are near.", "geneva": "Heare, yee that are farre off, what I haue done, and ye that are neere, know my power.", "wycliffe": "Ye that ben fer, here what thingis Y haue do; and, ye neiyboris, knowe my strengthe.", "rotherham": "Hear—ye that are far off. what I have done, And know—ye that are near my might:", "darby": "Hear, ye that are far off, what I have done; and ye that are near, acknowledge my might.", "twenty": "", "jps": "Hear, ye that are far off, what I have done; and, ye that are near, acknowledge My might.", "acv": "Hear, ye who are far off, what I have done, and ye who are near, acknowledge my might.", "anderson": "", "haweis": "", "noyes": "Hear, ye that are far off, what I have done; Mark, ye that are near, my power!", "webster": "Ye [that are] far off, hear what I have done; and ye [that are] near, acknowledge my might.", "vulgate": "audite qui longe estis quae fecerim et cognoscite vicini fortitudinem meam;", "brenton": "They that are afar off shall hear what I have done; they that draw nigh shall know my strength."}}, {"v": 14, "ref": "33:14", "o": "פָּחֲד֤וּ בְ/צִיּוֹן֙ חַטָּאִ֔ים אָחֲזָ֥ה רְעָדָ֖ה חֲנֵפִ֑ים מִ֣י יָג֣וּר לָ֗/נוּ אֵ֚שׁ אוֹכֵלָ֔ה מִי יָג֥וּר לָ֖/נוּ מוֹקְדֵ֥י עוֹלָֽם", "en": {"kjv": "The sinners in Zion are afraid; fearfulness hath surprised the hypocrites. Who among us shall dwell with the devouring fire? who among us shall dwell with everlasting burnings?", "web": "The sinners in Zion are afraid. Trembling has seized the godless ones. Who among us can live with the devouring fire? Who among us can live with everlasting burning?", "bsb": "The sinners in Zion are afraid; trembling grips the ungodly: “Who of us can dwell with a consuming fire? Who of us can dwell with everlasting flames?”", "asv": "The sinners in Zion are afraid; trembling hath seized the godless ones: Who among us can dwell with the devouring fire? who among us can dwell with everlasting burnings?", "ylt": "Afraid in Zion have been sinners, Seized hath trembling the profane: Who doth dwell for us--consuming fire, Who doth dwell for us--burnings of the age?", "dra": "The sinners in Sion are afraid, trembling hath seized upon the hypocrites. Which of you can dwell with devouring fire? which of you shall dwell with everlasting burnings?", "bbe": "The sinners in Zion are full of fear; the haters of God are shaking with wonder. Who among us may keep his place before the burning fire? who among us may see the eternal burnings?", "geneva": "The sinners in Zion are afraide: a feare is come vpon the hypocrites: who among vs shall dwel with the deuouring fire? who among vs shall dwell with the euerlasting burnings?", "wycliffe": "Synneris ben al to-brokun in Syon, tremblyng weldide ipocritis; who of you mai dwelle with fier deuowringe? who of you schal dwelle with euerlastinge brennyngis?", "rotherham": "Terror-stricken in Zion,—are sinners, Shuddering hath seized the impious,—Who among us can sojourn with a fire that devoureth? Who among us can sojourn with burnings age-abiding?", "darby": "The sinners in Zion are afraid; trembling hath surprised the hypocrites: Who among us shall dwell with the consuming fire? who among us shall dwell with everlasting flames?", "twenty": "", "jps": "The sinners in Zion are afraid; trembling hath seized the ungodly: 'Who among us shall dwell with the devouring fire? Who among us shall dwell with everlasting burnings?'", "acv": "The sinners in Zion are afraid. Trembling has seized the profane. Who among us can dwell with the devouring fire? Who among us can dwell with everlasting burnings?", "anderson": "", "haweis": "", "noyes": "The sinners in Zion are struck with dread; Terror hath seized upon the unrighteous: \"Who among us can dwell in devouring fire? Who among us can dwell in everlasting flames?\"", "webster": "The sinners in Zion are afraid; fearfulness hath surprised the hypocrites. Who among us shall dwell with the devouring fire? who among us shall dwell with everlasting burnings?", "vulgate": "conterriti sunt in Sion peccatores possedit tremor hypocritas quis poterit habitare de vobis cum igne devorante quis habitabit ex vobis cum ardoribus sempiternis;", "brenton": "The sinners in Sion have departed; trembling shall seize the ungodly. Who will tell you that a fire is kindled? Who will tell you of the eternal place?"}}, {"v": 15, "ref": "33:15", "o": "הֹלֵ֣ךְ צְדָק֔וֹת וְ/דֹבֵ֖ר מֵֽישָׁרִ֑ים מֹאֵ֞ס בְּ/בֶ֣צַע מַעֲשַׁקּ֗וֹת נֹעֵ֤ר כַּפָּי/ו֙ מִ/תְּמֹ֣ךְ בַּ/שֹּׁ֔חַד אֹטֵ֤ם אָזְנ/וֹ֙ מִ/שְּׁמֹ֣עַ דָּמִ֔ים וְ/עֹצֵ֥ם עֵינָ֖י/ו מֵ/רְא֥וֹת בְּ/רָֽע", "en": {"kjv": "He that walketh righteously, and speaketh uprightly; he that despiseth the gain of oppressions, that shaketh his hands from holding of bribes, that stoppeth his ears from hearing of blood, and shutteth his eyes from seeing evil;", "web": "He who walks righteously, and speaks blamelessly; He who despises the gain of oppressions, who gestures with his hands, refusing to take a bribe, who stops his ears from hearing of blood, and shuts his eyes from looking at evil—", "bsb": "He who walks righteously and speaks with sincerity, who refuses gain from extortion, whose hand never takes a bribe, who stops his ears against murderous plots and shuts his eyes tightly against evil—", "asv": "He that walketh righteously, and speaketh uprightly; he that despiseth the gain of oppressions, that shaketh his hands from taking a bribe, that stoppeth his ears from hearing of blood, and shutteth his eyes from looking upon evil:", "ylt": "Whoso is walking righteously, And is speaking uprightly, Kicking against gain of oppressions, Shaking his hands from taking hold on a bribe, Stopping his ear from hearing of blood, And shutting his eyes from looking on evil,", "dra": "He that walketh in justices, and speaketh truth, that casteth away avarice by oppression, and shaketh his hands from all bribes, that stoppeth his ears lest he hear blood, and shutteth his eyes that he may see no evil.", "bbe": "He whose ways are true, and whose words are upright; he who gives no thought to the profits of false acts, whose hands have not taken rewards, who will have no part in putting men to death, and whose eyes are shut against evil;", "geneva": "Hee that walketh in iustice, and speaketh righteous things, refusing gaine of oppression, shaking his handes from taking of gifts, stopping his eares from hearing of blood, and shutting his eyes from seeing euill.", "wycliffe": "He that goith in riytfulnessis, and spekith treuthe; he that castith awei aueryce of fals calenge, and schakith awei his hondis fro al yifte; he that stoppith his eeris, that he heere not blood, and closith his iyen, that he se not yuel.", "rotherham": "He that walketh righteously, And speaketh uprightly,—He that refuseth the gain of exactions That shaketh his hands free from holding a bribe, That stoppeth his ear from hearkening to deeds of blood, And shutteth his eyes from giving countenance to wrong,", "darby": "— He that walketh righteously, and speaketh uprightly; he that despiseth the gain of oppressions, that shaketh his hands from taking hold of bribes, that stoppeth his ears from hearing of blood, and shutteth his eyes from seeing evil:", "twenty": "", "jps": "He that walketh righteously, and speaketh uprightly; he that despiseth the gain of oppressions, that shaketh his hands from holding of bribes, that stoppeth his ears from hearing of blood, and shutteth his eyes from looking upon evil;", "acv": "He who walks righteously, and speaks uprightly. He who despises the gain of oppressions, who shakes away his hands from taking a bribe, who stops his ears from hearing of blood, and shuts his eyes from looking upon evil.", "anderson": "", "haweis": "", "noyes": "He that walketh in righteousness, And speaketh that which is right, That despiseth the gain of oppression, And shaketh his hands from bribery, That stoppeth his ears, so as not to hear of blood, And shutteth his eyes, so as not to behold iniquity.", "webster": "He that walketh righteously, and speaketh uprightly; he that despiseth the gain of oppressions, that shaketh his hands from holding of bribes, that stoppeth his ears from hearing of blood, and shutteth his eyes from seeing evil;", "vulgate": "qui ambulat in iustitiis et loquitur veritates qui proicit avaritiam ex calumnia et excutit manus suas ab omni munere qui obturat aures suas ne audiat sanguinem et claudit oculos suos ne videat malum;", "brenton": "He that walks in righteousness, speaking rightly, hating transgression and iniquity, and shaking his hands from gifts, stopping his ears that he should not hear the judgment of blood, shutting his eyes that he should not see injustice."}}, {"v": 16, "ref": "33:16", "o": "ה֚וּא מְרוֹמִ֣ים יִשְׁכֹּ֔ן מְצָד֥וֹת סְלָעִ֖ים מִשְׂגַּבּ֑/וֹ לַחְמ֣/וֹ נִתָּ֔ן מֵימָ֖י/ו נֶאֱמָנִֽים", "en": {"kjv": "He shall dwell on high: his place of defence shall be the munitions of rocks: bread shall be given him; his waters shall be sure.", "web": "he will dwell on high. His place of defense will be the fortress of rocks. His bread will be supplied. His waters will be sure.", "bsb": "he will dwell on the heights; the mountain fortress will be his refuge; his food will be provided and his water assured.", "asv": "He shall dwell on high; his place of defence shall be the munitions of rocks; his bread shall be given him; his waters shall be sure.", "ylt": "He high places doth inhabit, Strongholds of rock are his high tower, His bread hath been given, his waters stedfast.", "dra": "He shall dwell on high, the fortifications of rocks shall be his highness: bread is given him, his waters are sure.", "bbe": "He will have a place on high: he will be safely shut in by the high rocks: his bread will be given to him; his waters will be certain.", "geneva": "He shall dwell on hie: his defence shall be the munitions of rockes: bread shalbe giuen him, and his waters shalbe sure.", "wycliffe": "This man schal dwelle in hiy thingis, the strengthis of stoonys ben the hiynesse of hym; breed is youun to hym, hise watris ben feithful.", "rotherham": "He, the heights, shall inhabit, A stronghold of crags, shall be his refuge,—His bread, hath been delivered, His waters, have been made sure,", "darby": "he shall dwell on high, the fortresses of the rocks shall be his high retreat; bread shall be given him, his water shall be sure.", "twenty": "", "jps": "He shall dwell on high; his place of defence shall be the munitions of rocks; his bread shall be given, his waters shall be sure.", "acv": "He shall dwell on high. His place of defense shall be the munitions of rocks. His bread shall be given. His waters shall be sure.", "anderson": "", "haweis": "", "noyes": "He shall dwell on high; The strongholds of rocks shall be his defence; His bread shall be given him; His water shall not fail.", "webster": "He shall dwell on high: his place of defense [shall be] the munitions of rocks: bread shall be given him; his waters [shall be] sure.", "vulgate": "iste in excelsis habitabit munimenta saxorum sublimitas eius panis ei datus est aquae eius fideles sunt;", "brenton": "he shall dwell in a high cave of a strong rock: bread shall be given him, and his water shall be sure."}}, {"v": 17, "ref": "33:17", "o": "מֶ֥לֶךְ בְּ/יָפְי֖/וֹ תֶּחֱזֶ֣ינָה עֵינֶ֑י/ךָ תִּרְאֶ֖ינָה אֶ֥רֶץ מַרְחַקִּֽים", "en": {"kjv": "Thine eyes shall see the king in his beauty: they shall behold the land that is very far off.", "web": "Your eyes will see the king in his beauty. They will see a distant land.", "bsb": "Your eyes will see the King in His beauty and behold a land that stretches afar.", "asv": "Thine eyes shall see the king in his beauty: they shall behold a land that reacheth afar.", "ylt": "A king in his beauty, see do thine eyes, They see a land afar off.", "dra": "His eyes shall see the king in his beauty, they shall see the land far off.", "bbe": "Your eyes will see the king in his glory: they will be looking on a far-stretching land.", "geneva": "Thine eyes shall see the King in his glory: they shall beholde the lande farre off.", "wycliffe": "Thei schulen se the kyng in his fairnesse; the iyen of hym schulen biholde the londe fro fer.", "rotherham": "Of a king, in his beauty, shall thine eyes have vision: They shall see a land that stretcheth afar.", "darby": "Thine eyes shall see the King in his beauty; they shall behold the land that is far off.", "twenty": "", "jps": "Thine eyes shall see the king in his beauty; they shall behold a land stretching afar.", "acv": "Thine eyes shall see the king in his beauty. They shall behold a land that reaches afar.", "anderson": "", "haweis": "", "noyes": "Thine eyes shall see the king in his glory They shall survey a wide-extended land.", "webster": "Thy eyes shall see the king in his beauty: they shall behold the land that is very far off.", "vulgate": "regem in decore suo videbunt oculi eius cernent terram de longe;", "brenton": "Ye shall see a king with glory: your eyes shall behold a land from afar."}}, {"v": 18, "ref": "33:18", "o": "לִבְּ/ךָ֖ יֶהְגֶּ֣ה אֵימָ֑ה אַיֵּ֤ה סֹפֵר֙ אַיֵּ֣ה שֹׁקֵ֔ל אַיֵּ֖ה סֹפֵ֥ר אֶת הַ/מִּגְדָּלִֽים", "en": {"kjv": "Thine heart shall meditate terror. Where is the scribe? where is the receiver? where is he that counted the towers?", "web": "Your heart will meditate on the terror. Where is he who counted? Where is he who weighed? Where is he who counted the towers?", "bsb": "Your mind will ponder the former terror: “Where is he who tallies? Where is he who weighs? Where is he who counts the towers?”", "asv": "Thy heart shall muse on the terror: Where is he that counted, where is he that weighed the tribute? where is he that counted the towers?", "ylt": "Thy heart doth meditate terror, Where is he who is counting? Where is he who is weighing? Where is he who is counting the towers?", "dra": "Thy heart shall meditate fear: where is the learned? where is he that pondered the words of the law? where is the teacher of little ones?", "bbe": "Your heart will give thought to the cause of your fear: where is the scribe, where is he who made a record of the payments, where is he by whom the towers were numbered?", "geneva": "Thine heart shall meditate feare, Where is the scribe? where is the receiuer? where is hee that counted the towres?", "wycliffe": "Eliachym, thin herte schal bithenke drede; where is the lettrid man? Where is he that weieth the wordis of the lawe? where is the techere of litle children?", "rotherham": "Thy heart, may murmur in terror,—Where is the scribe? Where—the receiver? Where—he that maketh a list of the towers?", "darby": "Thy heart shall meditate on terror: Where is the scribe? where is the receiver? where is he that counted the towers?", "twenty": "", "jps": "Thy heart shall muse on the terror: 'Where is he that counted, where is he that weighed? Where is he that counted the towers?'", "acv": "Thy heart shall muse on the terror. Where is he who counted? Where is he who weighed the tribute? Where is he who counted the towers?", "anderson": "", "haweis": "", "noyes": "Thy heart shall meditate on the past terror: \"Where now is the scribe? Where the weigher of tribute? Where he that numbered the towers?\"", "webster": "Thy heart shall meditate terror. Where [is] the scribe? where [is] the receiver? where [is] he that counted the towers?", "vulgate": "cor tuum meditabitur timorem ubi est litteratus ubi legis verba ponderans ubi doctor parvulorum;", "brenton": "Your soul shall meditate terror. Where are the scribes? where are the counsellors, where is he that numbers them that are growing up,"}}, {"v": 19, "ref": "33:19", "o": "אֶת עַ֥ם נוֹעָ֖ז לֹ֣א תִרְאֶ֑ה עַ֣ם עִמְקֵ֤י שָׂפָה֙ מִ/שְּׁמ֔וֹעַ נִלְעַ֥ג לָשׁ֖וֹן אֵ֥ין בִּינָֽה", "en": {"kjv": "Thou shalt not see a fierce people, a people of a deeper speech than thou canst perceive; of a stammering tongue, that thou canst not understand.", "web": "You will no longer see the fierce people, a people of a deep speech that you can’t comprehend, with a strange language that you can’t understand.", "bsb": "You will no longer see the insolent, a people whose speech is unintelligible, who stammer in a language you cannot understand.", "asv": "Thou shalt not see the fierce people, a people of a deep speech that thou canst not comprehend, of a strange tongue that thou canst not understand.", "ylt": "The strong people thou seest not, A people deeper of lip than to be understood, Of a scorned tongue, there is no understanding.", "dra": "The shameless people thou shalt not see, the people of profound speech: so that thou canst not understand the eloquence of his tongue, in whom there is no wisdom.", "bbe": "Never again will you see the cruel people, a people whose tongue has no sense for you; whose language is strange to you.", "geneva": "Thou shalt not see a fierce people, a people of a darke speache, that thou canst not perceiue, and of a stammering tongue that thou canst not vnderstande.", "wycliffe": "Thou schalt not se a puple vnwijs, a puple of hiy word, so that thou maist not vndurstonde the fair speking of his tunge, in which puple is no wisdom.", "rotherham": "The fierce people, shalt thou not see,—The people of too deep a lip to be understood, of too barbarous a tongue for thee to comprehend.", "darby": "Thou shalt no more see the fierce people, a people of a deeper speech than thou canst comprehend, of a stammering tongue that cannot be understood.", "twenty": "", "jps": "Thou shalt not see the fierce people; a people of a deep speech that thou canst not perceive, of a stammering tongue that thou canst not understand.", "acv": "Thou shall not see the fierce people, a people of a deep speech that thou cannot comprehend, of a strange tongue that thou cannot understand.", "anderson": "", "haweis": "", "noyes": "Thou shalt see no more a fierce people, A people of a dark language, which thou couldst not hear, And of a barbarous tongue, which thou couldst not understand;", "webster": "Thou shalt not see a fierce people, a people of deeper speech than thou canst perceive; of a stammering tongue, [that thou canst] not understand.", "vulgate": "populum inpudentem non videbis populum alti sermonis ita ut non possis intellegere disertitudinem linguae eius in quo nulla est sapientia;", "brenton": "even the small and great people? with whom he took not counsel, neither did he understand a people of deep speech, so that a despised people should not hear, and there is no understanding to him that hears."}}, {"v": 20, "ref": "33:20", "o": "חֲזֵ֣ה צִיּ֔וֹן קִרְיַ֖ת מֽוֹעֲדֵ֑/נוּ עֵינֶי/ךָ֩ תִרְאֶ֨ינָה יְרוּשָׁלִַ֜ם נָוֶ֣ה שַׁאֲנָ֗ן אֹ֤הֶל בַּל יִצְעָן֙ בַּל יִסַּ֤ע יְתֵֽדֹתָי/ו֙ לָ/נֶ֔צַח וְ/כָל חֲבָלָ֖י/ו בַּל יִנָּתֵֽקוּ", "en": {"kjv": "Look upon Zion, the city of our solemnities: thine eyes shall see Jerusalem a quiet habitation, a tabernacle that shall not be taken down; not one of the stakes thereof shall ever be removed, neither shall any of the cords thereof be broken.", "web": "Look at Zion, the city of our appointed festivals. Your eyes will see Jerusalem, a quiet habitation, a tent that won’t be removed. Its stakes will never be plucked up, nor will any of its cords be broken.", "bsb": "Look upon Zion, the city of our appointed feasts. Your eyes will see Jerusalem, a peaceful pasture, a tent that does not wander; its tent pegs will not be pulled up, nor will any of its cords be broken.", "asv": "Look upon Zion, the city of our solemnities: thine eyes shall see Jerusalem a quiet habitation, a tent that shall not be removed, the stakes whereof shall never be plucked up, neither shall any of the cords thereof be broken.", "ylt": "See Zion, the city of our meetings, Thine eyes see Jerusalem a quiet habitation, A tent not taken down, Not removed are its pins for ever, And none of its cords are broken.", "dra": "Look upon Sion the city of our solemnity: thy eyes shall see Jerusalem, a rich habitation, a tabernacle that cannot be removed: neither shall the nails thereof be taken away for ever, neither shall any of the cords thereof be broken.", "bbe": "Let your eyes be resting on Zion, the town of our holy feasts: you will see Jerusalem, a quiet resting-place, a tent which will not be moved, whose tent-pins will never be pulled up, and whose cords will never be broken.", "geneva": "Looke vpon Zion the citie of our solemne feastes: thine eyes shall see Ierusalem a quiet habitation, a Tabernacle that can not be remooued: and the stakes thereof can neuer be taken away, neither shall any of the cordes thereof be broken.", "wycliffe": "Biholde thou Sion, the citee of youre solempnyte; thin iyen schulen se Jerusalem, a riche citee, a tabernacle that mai not be borun ouer, nether the nailis therof schulen be takun awei withouten ende; and alle the cordis therof schulen not be brokun.", "rotherham": "Look thou on Zion, the city of our appointed feast,—Thine own eyes, shall see Jerusalem—A home of comfort A tent which shall not be packed up—Whose pins shall not be pulled out, for ever, And none of, whose cords, shall be broken.", "darby": "Look upon Zion, the city of our solemnities: thine eyes shall see Jerusalem a quiet habitation, a tent that shall not be removed, the stakes whereof shall never be pulled up, neither shall any of its cords be broken;", "twenty": "", "jps": "Look upon Zion, the city of our solemn gatherings; thine eyes shall see Jerusalem a peaceful habitation, a tent that shall not be removed, the stakes whereof shall never be plucked up, neither shall any of the cords thereof be broken.", "acv": "Look upon Zion, the city of our solemnities. Thine eyes shall see Jerusalem a quiet habitation, a tent that shall not be removed. The stakes of which shall never be plucked up, nor shall any of the cords of it be broken.", "anderson": "", "haweis": "", "noyes": "Thou shalt see Zion, the city of our solemn feasts; Thine eyes shall behold Jerusalem, as a quiet habitation. A tent that shall never be moved, Whose stakes shall never be taken away, And whose cords shall never be broken.", "webster": "Look upon Zion, the city of our solemnities: thy eyes shall see Jerusalem a quiet habitation, a tabernacle [that] shall not be taken down; not one of its stakes shall ever be removed, neither shall any of its cords be broken.", "vulgate": "respice Sion civitatem sollemnitatis nostrae oculi tui videbunt Hierusalem habitationem opulentam tabernaculum quod nequaquam transferri poterit nec auferentur clavi eius in sempiternum et omnes funiculi eius non rumpentur;", "brenton": "Behold the city of Sion, our refuge: thine eyes shall behold Jerusalem, a rich city, tabernacles which shall not be shaken, neither shall the pins of her tabernacle be moved for ever, neither shall her cords be at all broken:"}}, {"v": 21, "ref": "33:21", "o": "כִּ֣י אִם שָׁ֞ם אַדִּ֤יר יְהוָה֙ לָ֔/נוּ מְקוֹם נְהָרִ֥ים יְאֹרִ֖ים רַחֲבֵ֣י יָדָ֑יִם בַּל תֵּ֤לֶךְ בּ/וֹ֙ אֳנִי שַׁ֔יִט וְ/צִ֥י אַדִּ֖יר לֹ֥א יַעַבְרֶֽ/נּוּ", "en": {"kjv": "But there the glorious Lord will be unto us a place of broad rivers and streams; wherein shall go no galley with oars, neither shall gallant ship pass thereby.", "web": "But there Yahweh will be with us in majesty, a place of broad rivers and streams, in which no galley with oars will go, neither will any gallant ship pass by there.", "bsb": "But there the Majestic One, our LORD, will be for us a place of rivers and wide canals, where no galley with oars will row, and no majestic vessel will pass.", "asv": "But there Jehovah will be with us in majesty, a place of broad rivers and streams, wherein shall go no galley with oars, neither shall gallant ship pass thereby.", "ylt": "But there mighty is Jehovah for us, A place of rivers--streams broad of sides, No ship with oars doth go into it, And a mighty ship doth not pass over it.", "dra": "Because only there our Lord is magnificent: a place of rivers, very broad and spacious streams: no ship with oars shall pass by it, neither shall the great galley pass through it.", "bbe": "But there the Lord will be with us in his glory, ... wide rivers and streams; where no boat will go with blades, and no fair ship will be sailing.", "geneva": "For surely there the mightie Lord will be vnto vs, as a place of floods and broade riuers, whereby shall passe no shippe with oares, neither shall great shippe passe thereby.", "wycliffe": "For oneli the worschipful doere oure Lord God is there; the place of floodis is strondis ful large and opyn; the schip of roweris schal not entre bi it, nethir a greet schip schal passe ouer it.", "rotherham": "But, there shall Yahweh be our majestic one, A place of rivers—streams broad on both hands, Wherein shall go no galley with oars, Neither shall majestic ship traverse it;", "darby": "but there Jehovah is unto us glorious, — a place of rivers, of broad streams: no galley with oars shall go there, neither shall gallant ship pass thereby.", "twenty": "", "jps": "But there HaShem will be with us in majesty, in a place of broad rivers and streams; wherein shall go no galley with oars, neither shall gallant ship pass thereby.", "acv": "But Jehovah will be with us there in majesty. A place of broad rivers and streams, in which shall go no galley with oars, nor shall a gallant ship pass thereby.", "anderson": "", "haweis": "", "noyes": "For there the glorious Jehovah will be to us Instead of rivers and broad streams, Which no oared galley shall pass, And no gallant ship go through.", "webster": "But there the glorious LORD [will be] to us a place of broad rivers [and] streams; in which shall go no galley with oars, neither shall gallant ship pass through it.", "vulgate": "quia solummodo ibi magnificus Dominus noster locus fluviorum rivi latissimi et patentes non transibit per eum navis remigum neque trieris magna transgredietur eum;", "brenton": "for the name of the Lord is great to you: ye shall have a place, even rivers and wide and spacious channels: thou shalt not go this way, neither a vessel with oars go thereby."}}, {"v": 22, "ref": "33:22", "o": "כִּ֤י יְהוָה֙ שֹׁפְטֵ֔/נוּ יְהוָ֖ה מְחֹקְקֵ֑/נוּ יְהוָ֥ה מַלְכֵּ֖/נוּ ה֥וּא יוֹשִׁיעֵֽ/נוּ", "en": {"kjv": "For the Lord is our judge, the Lord is our lawgiver, the Lord is our king; he will save us.", "web": "For Yahweh is our judge. Yahweh is our lawgiver. Yahweh is our king. He will save us.", "bsb": "For the LORD is our Judge, the LORD is our lawgiver, the LORD is our King. It is He who will save us.", "asv": "For Jehovah is our judge, Jehovah is our lawgiver, Jehovah is our king; he will save us.", "ylt": "For Jehovah our judge, Jehovah our lawgiver, Jehovah our king--He doth save us.", "dra": "For the Lord is our judge, the Lord is our lawgiver, the Lord is our king: he will save us.", "bbe": "For the Lord is our judge, the Lord is our law-giver, the Lord is our king; he will be our saviour.", "geneva": "For the Lord is our Iudge, the Lord is our lawe giuer: the Lord is our King, he will saue vs.", "wycliffe": "For whi the Lord is oure iuge, the Lord is oure lawe yyuere, the Lord is oure kyng; he schal saue vs.", "rotherham": "For, Yahweh is our judge, Yahweh, is our lawgiver,—Yahweh, is our king, He will save us!", "darby": "For Jehovah is our judge, Jehovah, our lawgiver, Jehovah, our king: he will save us.", "twenty": "", "jps": "For HaShem is our Judge, HaShem is our Lawgiver, HaShem is our King; He will save us.", "acv": "For Jehovah is our judge. Jehovah is our lawgiver. Jehovah is our king, he will save us.", "anderson": "", "haweis": "", "noyes": "For Jehovah is our judge; Jehovah is our lawgiver; Jehovah is our king; it is he that will save us.", "webster": "For the LORD [is] our judge, the LORD [is] our lawgiver, the LORD [is] our king; he will save us.", "vulgate": "Dominus enim iudex noster Dominus legifer noster Dominus rex noster ipse salvabit nos;", "brenton": "For my God is great: the Lord our judge shall not pass me by: the Lord is our prince, the Lord is our king; the Lord, he shall save us."}}, {"v": 23, "ref": "33:23", "o": "נִטְּשׁ֖וּ חֲבָלָ֑יִ/ךְ בַּל יְחַזְּק֤וּ כֵן תָּרְנָ/ם֙ בַּל פָּ֣רְשׂוּ נֵ֔ס אָ֣ז חֻלַּ֤ק עַֽד שָׁלָל֙ מַרְבֶּ֔ה פִּסְחִ֖ים בָּ֥זְזוּ בַֽז", "en": {"kjv": "Thy tacklings are loosed; they could not well strengthen their mast, they could not spread the sail: then is the prey of a great spoil divided; the lame take the prey.", "web": "Your rigging is untied. They couldn’t strengthen the foot of their mast. They couldn’t spread the sail. Then the prey of a great plunder was divided. The lame took the prey.", "bsb": "Your ropes are slack; they cannot secure the mast or spread the sail. Then an abundance of spoils will be divided, and even the lame will carry off plunder.", "asv": "Thy tacklings are loosed; they could not strengthen the foot of their mast, they could not spread the sail: then was the prey of a great spoil divided; the lame took the prey.", "ylt": "Left have been thy ropes, They strengthen not rightly their mast, They have not spread out a sail, Then apportioned hath been a prey of much spoil, The lame have taken spoil.", "dra": "Thy tacklings are loosed, and they shall be of no strength: thy mast shall be in such condition, that thou shalt not be able to spread the flag. Then shall the spoils of much prey be divided: the lame shall take the spoil.", "bbe": "Your cords have become loose; they were not able to make strong the support of their sails, the sail was not stretched out: then the blind will take much property, the feeble-footed will make division of the goods of war.", "geneva": "Thy cordes are loosed: they could not well strengthen their maste, neither coulde they spread the saile: then shall the praye be deuided for a great spoile: yea, the lame shall take away the pray.", "wycliffe": "Thi roopis ben slakid, but tho schulen not auaile; thi mast schal be so, that thou mow not alarge a signe. Thanne the spuylis of many preyes schulen be departid, crokid men schulen rauysche raueyn.", "rotherham": "Loosed are thy ropes,—They cannot strengthen the socket of their mast They have not unfurled a sail Now, can be apportioned spoil, in abundance, The lame, have captured prey!", "darby": "Thy tacklings are loosed; they strengthen not the socket of their mast, they cannot spread the sail: then is the prey of a great spoil divided; the lame take the prey.", "twenty": "", "jps": "Thy tacklings are loosed; they do not hold the stand of their mast, they do not spread the sail; then is the prey of a great spoil divided; the lame take the prey.", "acv": "Thy tacklings are loosed. They could not strengthen the foot of their mast. They could not spread the sail. Then the prey of a great spoil was divided. The lame took the prey.", "anderson": "", "haweis": "", "noyes": "Thy ropes hang loose; They cannot hold the mast-socket, Nor can they spread the sail. Then shall a great spoil be divided; Even the lame shall take the prey.", "webster": "Thy tacklings are loosed; they could not well strengthen their mast, they could not spread the sail: then is the prey of a great spoil divided; the lame take the prey.", "vulgate": "laxati sunt funiculi tui sed non praevalebunt sic erit malus tuus ut dilatare signum non queas tunc dividentur spolia praedarum multarum claudi diripient rapinam;", "brenton": "Thy cords are broken, for they had no strength: thy meat has given way, it shall not spread the sails, it shall not bear a signal, until it be given up for plunder; therefore shall many lame men take spoil."}}, {"v": 24, "ref": "33:24", "o": "וּ/בַל יֹאמַ֥ר שָׁכֵ֖ן חָלִ֑יתִי הָ/עָ֛ם הַ/יֹּשֵׁ֥ב בָּ֖/הּ נְשֻׂ֥א עָוֺֽן", "en": {"kjv": "And the inhabitant shall not say, I am sick: the people that dwell therein shall be forgiven their iniquity.", "web": "The inhabitant won’t say, “I am sick.” The people who dwell therein will be forgiven their iniquity.", "bsb": "And no resident of Zion will say, “I am sick.” The people who dwell there will be forgiven of iniquity.", "asv": "And the inhabitant shall not say, I am sick: the people that dwell therein shall be forgiven their iniquity.", "ylt": "Nor doth an inhabitant say, `I was sick,' The people that is dwelling in it, is forgiven of iniquity!", "dra": "Neither shall he that is near, say: I am feeble. The people that dwell therein, shall have their iniquity taken away from them.", "bbe": "And the men of Zion will not say, I am ill: for its people will have forgiveness for their sin.", "geneva": "And none inhabitant shall say, I am sicke: the people that dwell therein, shall haue their iniquitie forgiuen.", "wycliffe": "And a neiybore schal seie, Y was not sijk; the puple that dwellith in that Jerusalem, wickidnesse schal be takun awei fro it.", "rotherham": "Neither shall the inhabitant say. I am sick,—the people who dwell therein, have been forgiven iniquity.", "darby": "And the inhabitant shall not say, I am sick: the people that dwell therein shall be forgiven [their] iniquity.", "twenty": "", "jps": "And the inhabitant shall not say: 'I am sick'; the people that dwell therein shall be forgiven their iniquity.", "acv": "And the inhabitant shall not say, I am sick. The people who dwell in it shall be forgiven their iniquity.", "anderson": "", "haweis": "", "noyes": "No inhabitant shall say, I am sick; The people that dwell therein shall be forgiven their iniquity.", "webster": "And the inhabitants shall not say, I am sick: the people that dwell therein [shall be] forgiven [their] iniquity.", "vulgate": "nec dicet vicinus elangui populus qui habitat in ea auferetur ab eo iniquitas;", "brenton": "And the people dwelling among them shall by no means say, I am in pain: for their sin shall be forgiven them."}}]}, {"c": 34, "verses": [{"v": 1, "ref": "34:1", "o": "קִרְב֤וּ גוֹיִם֙ לִ/שְׁמֹ֔עַ וּ/לְאֻמִּ֖ים הַקְשִׁ֑יבוּ תִּשְׁמַ֤ע הָ/אָ֨רֶץ֙ וּ/מְלֹאָ֔/הּ תֵּבֵ֖ל וְ/כָל צֶאֱצָאֶֽי/הָ", "en": {"kjv": "Come near, ye nations, to hear; and hearken, ye people: let the earth hear, and all that is therein; the world, and all things that come forth of it.", "web": "Come near, you nations, to hear! Listen, you peoples. Let the earth and all it contains hear; the world, and everything that comes from it.", "bsb": "Come near, O nations, to listen; pay attention, O peoples. Let the earth hear, and all that fills it, the world and all that springs from it.", "asv": "Come near, ye nations, to hear; and hearken, ye peoples: let the earth hear, and the fulness thereof; the world, and all things that come forth from it.", "ylt": "Come near, ye nations, to hear, And ye peoples, give attention, Hear doth the earth and its fulness, The world, and all its productions.", "dra": "Come near, ye Gentiles, and hear, and hearken, ye people: let the earth hear, and all that is therein, the world, and every thing that cometh forth of it.", "bbe": "Come near, you nations, and give ear; take note, you peoples: let the earth and everything in it give ear; the world and all those living in it.", "geneva": "Come neere, ye nations and heare, and hearken, ye people: let the earth heare and all that is therein, the world and al that proceedeth thereof.", "wycliffe": "Neiye, ye hethene men, and here; and ye puplis, perseyue; the erthe, and the fulnesse therof, the world, and al buriownyng therof, here ye.", "rotherham": "Come near ye nations to hear, And, ye races, attend,—Let the earth hear, and the fulness thereof, The world and all things produced therefrom:", "darby": "Come near, ye nations, to hear; and hearken, ye peoples: let the earth hear, and all its fulness; the world, and all that cometh forth of it.", "twenty": "", "jps": "Come near, ye nations, to hear, and attend, ye peoples; let the earth hear, and the fulness thereof, the world, and all things that come forth of it.", "acv": "Come near, ye nations, to hear. And hearken, ye peoples. Let the earth hear, and the fullness thereof, the world, and all things that come forth from it.", "anderson": "", "haweis": "", "noyes": "Draw near, O ye nations, and hear! Attend, O ye people! Let the earth hear, and all that is therein; The world, and all that springs from it!", "webster": "Come near, ye nations, to hear; and hearken, ye people: let the earth hear, and all that is in it; the world, and all things that spring from it.", "vulgate": "accedite gentes et audite et populi adtendite audiat terra et plenitudo eius orbis et omne germen eius;", "brenton": "Draw near, ye nations; and hearken, ye princes; let the earth hear, and they that are in it; the world, and the people that are therein."}}, {"v": 2, "ref": "34:2", "o": "כִּ֣י קֶ֤צֶף לַֽ/יהוָה֙ עַל כָּל הַ/גּוֹיִ֔ם וְ/חֵמָ֖ה עַל כָּל צְבָאָ֑/ם הֶחֱרִימָ֖/ם נְתָנָ֥/ם לַ/טָּֽבַח", "en": {"kjv": "For the indignation of the Lord is upon all nations, and his fury upon all their armies: he hath utterly destroyed them, he hath delivered them to the slaughter.", "web": "For Yahweh is enraged against all the nations, and angry with all their armies. He has utterly destroyed them. He has given them over for slaughter.", "bsb": "The LORD is angry with all the nations and furious with all their armies. He will devote them to destruction; He will give them over to slaughter.", "asv": "For Jehovah hath indignation against all the nations, and wrath against all their host: he hath utterly destroyed them, he hath delivered them to the slaughter.", "ylt": "For wrath is to Jehovah against all the nations, And fury against all their host, He hath devoted them to destruction, He hath given them to slaughter.", "dra": "For the indignation of the Lord is upon all nations, and his fury upon all their armies: he hath killed them, and delivered them to slaughter.", "bbe": "For the Lord is angry with all the nations, and his wrath is burning against all their armies: he has put them to the curse, he has given them to destruction.", "geneva": "For the indignation of the Lord is vpon all nations, and his wrath vpon all their armies: hee hath destroyed them and deliuered them to the slaughter.", "wycliffe": "For whi indignacioun of the Lord is on alle folkis, and strong veniaunce on al the chyualrie of hem; he killide hem, and yaf hem in to sleyng.", "rotherham": "That Yahweh hath wrath against all the nations, and indignation against all their host,—He hath devoted them to destruction He hath delivered them to slaughter;", "darby": "For the wrath of Jehovah is against all the nations, and [his] fury against all their armies: he hath devoted them to destruction, he hath delivered them to the slaughter.", "twenty": "", "jps": "For HaShem hath indignation against all the nations, and fury against all their host; He hath utterly destroyed them, He hath delivered them to the slaughter.", "acv": "For Jehovah has indignation against all the nations, and wrath against all their host. He has utterly destroyed them. He has delivered them to the slaughter.", "anderson": "", "haweis": "", "noyes": "For the wrath of Jehovah is kindled against all the nations, And his fury against all their armies; He hath devoted them to destruction; He hath given them up to slaughter.", "webster": "For the indignation of the LORD [is] upon all nations, and [his] fury upon all their armies: he hath utterly destroyed them, he hath delivered them to the slaughter.", "vulgate": "quia indignatio Domini super omnes gentes et furor super universam militiam eorum interfecit eos et dedit eos in occisionem;", "brenton": "For the wrath of the Lord is upon all nations, and his anger upon the number of them, to destroy them, and give them up to slaughter."}}, {"v": 3, "ref": "34:3", "o": "וְ/חַלְלֵי/הֶ֣ם יֻשְׁלָ֔כוּ וּ/פִגְרֵי/הֶ֖ם יַעֲלֶ֣ה בָאְשָׁ֑/ם וְ/נָמַ֥סּוּ הָרִ֖ים מִ/דָּמָֽ/ם", "en": {"kjv": "Their slain also shall be cast out, and their stink shall come up out of their carcases, and the mountains shall be melted with their blood.", "web": "Their slain will also be cast out, and the stench of their dead bodies will come up; and the mountains will melt in their blood.", "bsb": "Their slain will be left unburied, and the stench of their corpses will rise; the mountains will flow with their blood.", "asv": "Their slain also shall be cast out, and the stench of their dead bodies shall come up; and the mountains shall be melted with their blood.", "ylt": "And their wounded are cast out, And their carcases cause their stench to ascend, And melted have been mountains from their blood.", "dra": "Their slain shall be cast forth, and out of their carcasses shall rise a stink: the mountains shall be melted with their blood.", "bbe": "Their dead bodies will be thick on the face of the earth, and their smell will come up, and the mountains will be flowing with their blood, and all the hills will come to nothing.", "geneva": "And their slaine shalbe cast out, and their stincke shall come vp out of their bodies, and the mountaines shalbe melted with their blood.", "wycliffe": "The slayn men of hem schulen be cast forth, and stynk schal stie of the careyns of hem; hillis schulen flete of the blood of hem.", "rotherham": "And their slain shall be cast out, And their carcases, the stench of them shall ascend,—And, the mountains, shall melt away with their blood.", "darby": "And their slain shall be cast out, and their stink shall come up from their carcases, and the mountains shall be melted with their blood.", "twenty": "", "jps": "Their slain also shall be cast out, and the stench of their carcasses shall come up, and the mountains shall be melted with their blood.", "acv": "Their slain also shall be cast out. And the stench of their dead bodies shall come up, and the mountains shall be melted with their blood.", "anderson": "", "haweis": "", "noyes": "Their slain shall be cast out; From their carcasses their stench shall ascend, And the mountains shall flow down with their blood.", "webster": "Their slain also shall be cast out, and their ill smell shall come up from their carcases, and the mountains shall be melted with their blood.", "vulgate": "interfecti eorum proicientur et de cadaveribus eorum ascendet fetor tabescent montes sanguine eorum;", "brenton": "And their slain shall be cast forth, and their corpses; and their ill savour shall come up, and the mountains shall be made wet with their blood."}}, {"v": 4, "ref": "34:4", "o": "וְ/נָמַ֨קּוּ֙ כָּל צְבָ֣א הַ/שָּׁמַ֔יִם וְ/נָגֹ֥לּוּ כַ/סֵּ֖פֶר הַ/שָּׁמָ֑יִם וְ/כָל צְבָאָ֣/ם יִבּ֔וֹל כִּ/נְבֹ֤ל עָלֶה֙ מִ/גֶּ֔פֶן וּ/כְ/נֹבֶ֖לֶת מִ/תְּאֵנָֽה", "en": {"kjv": "And all the host of heaven shall be dissolved, and the heavens shall be rolled together as a scroll: and all their host shall fall down, as the leaf falleth off from the vine, and as a falling fig from the fig tree.", "web": "All of the army of the sky will be dissolved. The sky will be rolled up like a scroll, and all its armies will fade away, as a leaf fades from off a vine or a fig tree.", "bsb": "All the stars of heaven will be dissolved. The skies will be rolled up like a scroll, and all their stars will fall like withered leaves from the vine, like foliage from the fig tree.", "asv": "And all the host of heaven shall be dissolved, and the heavens shall be rolled together as a scroll; and all their host shall fade away, as the leaf fadeth from off the vine, and as a fading leaf from the fig-tree.", "ylt": "And consumed have been all the host of the heavens, And rolled together as a book have been the heavens, And all their hosts do fade, As the fading of a leaf of a vine, And as the fading one of a fig-tree.", "dra": "And all the host of the heavens shall pine away, and the heavens shall be folded together as a book: and all their host shall fall down as the leaf falleth from the vine, and from the fig tree.", "bbe": "And the heavens will be rolled together like the roll of a book: and all their army will be gone, like a dead leaf from the vine, or a dry fruit from the fig-tree.", "geneva": "And all the hoste of heauen shalbe dissolued, and the heauens shall be folden like a booke: and all their hostes shall fall as the leafe falleth from the vine, and as it falleth from the figtree.", "wycliffe": "And al the chyualrie of heuenys schal faile, and heuenys schulen be foldid togidere as a book, and al the knyythod of tho schal flete doun, as the leef of a vyner and of a fige tre fallith doun.", "rotherham": "Then shall be dissolved all the host of the heavens, And the heavens shall roll up as a scroll,—Yea, all their host, shall fade—Like the fading and falling of a leaf from a vine, and Like what fadeth and falleth from a fig-tree.", "darby": "And all the host of the heavens shall be dissolved, and the heavens shall be rolled together as a scroll; and all their host shall fade away, as a leaf fadeth from off the vine, and as the withered [fruit] from the fig-tree.", "twenty": "", "jps": "And all the host of heaven shall moulder away, and the heavens shall be rolled together as a scroll; and all their host shall fall down, as the leaf falleth off from the vine, and as a falling fig from the fig-tree.", "acv": "And all the host of heaven shall be dissolved, and the heavens shall be rolled together as a scroll. And all their host shall fade away as the leaf fades from off the vine, and as a fading leaf from the fig tree.", "anderson": "", "haweis": "", "noyes": "And all the hosts of heaven shall melt away; And the heavens shall be rolled up like a scroll, And all their host shall fall down, As the withered leaf faileth from the vine, As the blighted fruit from the fig-tree.", "webster": "And all the host of heaven shall be dissolved, and the heavens shall be rolled together as a scroll: and all their hosts shall fall down, as the leaf falleth from the vine, and as a falling [fig] from the fig-tree.", "vulgate": "et tabescet omnis militia caelorum et conplicabuntur sicut liber caeli et omnis militia eorum defluet sicut defluit folium de vinea et de ficu;", "brenton": "And all the powers of the heavens shall melt, and the sky shall be rolled up like a scroll: and all the stars shall fall like leaves from a vine, and as leaves fall from a fig-tree."}}, {"v": 5, "ref": "34:5", "o": "כִּֽי רִוְּתָ֥ה בַ/שָּׁמַ֖יִם חַרְבִּ֑/י הִנֵּה֙ עַל אֱד֣וֹם תֵּרֵ֔ד וְ/עַל עַ֥ם חֶרְמִ֖/י לְ/מִשְׁפָּֽט", "en": {"kjv": "For my sword shall be bathed in heaven: behold, it shall come down upon Idumea, and upon the people of my curse, to judgment.", "web": "For my sword has drunk its fill in the sky. Behold, it will come down on Edom, and on the people of my curse, for judgment.", "bsb": "When My sword has drunk its fill in the heavens, then it will come down upon Edom, upon the people I have devoted to destruction.", "asv": "For my sword hath drunk its fill in heaven: behold, it shall come down upon Edom, and upon the people of my curse, to judgment.", "ylt": "For soaked in the heavens was My sword, Lo, on Edom it cometh down, On the people of My curse for judgment.", "dra": "For my sword is inebriated in heaven: behold it shall come down upon Idumea, and upon the people of my slaughter unto judgment.", "bbe": "For my sword in heaven is full of wrath: see, it is coming down on Edom, in punishment on the people of my curse.", "geneva": "For my sword shalbe drunken in the heauen: beholde, it shall come downe vpon Edom, euen vpon the people of my curse to iudgement.", "wycliffe": "For my swerd is fillid in heuene; lo! it schal come doun on Ydumee, and on the puple of my sleyng, to doom.", "rotherham": "For my sword hath been sated in the heavens,—Lo! upon Edom, shall it descend, Even on the people whom I have devoted to justice.", "darby": "For my sword is bathed in the heavens; behold, it shall come down upon Edom, and upon the people of my ban, to judgment.", "twenty": "", "jps": "For My sword hath drunk its fill in heaven; behold, it shall come down upon Edom, and upon the people of My ban, to judgment.", "acv": "For my sword has drunk its fill in heaven. Behold, it shall come down upon Edom, and upon the people of my curse, to judgment.", "anderson": "", "haweis": "", "noyes": "For my sword hath become drunk in heaven; Behold, upon Edom shall it descend, Upon the people under my curse, for vengeance.", "webster": "For my sword shall be bathed in heaven: behold, it shall come down upon Edom, and upon the people of my curse, to judgment.", "vulgate": "quoniam inebriatus est in caelo gladius meus ecce super Idumeam descendet et super populum interfectionis meae ad iudicium;", "brenton": "My sword has been made drunk in heaven: behold, it shall come down upon Idumea, and with judgment upon the people doomed to destruction."}}, {"v": 6, "ref": "34:6", "o": "חֶ֣רֶב לַ/יהוָ֞ה מָלְאָ֥ה דָם֙ הֻדַּ֣שְׁנָה מֵ/חֵ֔לֶב מִ/דַּ֤ם כָּרִים֙ וְ/עַתּוּדִ֔ים מֵ/חֵ֖לֶב כִּלְי֣וֹת אֵילִ֑ים כִּ֣י זֶ֤בַח לַֽ/יהוָה֙ בְּ/בָצְרָ֔ה וְ/טֶ֥בַח גָּד֖וֹל בְּ/אֶ֥רֶץ אֱדֽוֹם", "en": {"kjv": "The sword of the Lord is filled with blood, it is made fat with fatness, and with the blood of lambs and goats, with the fat of the kidneys of rams: for the Lord hath a sacrifice in Bozrah, and a great slaughter in the land of Idumea.", "web": "Yahweh’s sword is filled with blood. It is covered with fat, with the blood of lambs and goats, with the fat of the kidneys of rams; for Yahweh has a sacrifice in Bozrah, And a great slaughter in the land of Edom.", "bsb": "The sword of the LORD is bathed in blood. It drips with fat— with the blood of lambs and goats, with the fat of the kidneys of rams. For the LORD has a sacrifice in Bozrah, a great slaughter in the land of Edom.", "asv": "The sword of Jehovah is filled with blood, it is made fat with fatness, with the blood of lambs and goats, with the fat of the kidneys of rams; for Jehovah hath a sacrifice in Bozrah, and a great slaughter in the land of Edom.", "ylt": "A sword is to Jehovah--it hath been full of blood, It hath been made fat with fatness, With blood of lambs and he-goats. With fat of kidneys of rams, For a sacrifice is to Jehovah in Bozrah, And a great slaughter in the land of Edom.", "dra": "The sword of the Lord is filled with blood, it is made thick with the blood of lambs and buck goats, with the blood of rams full of marrow: for there is a victim of the Lord in Bosra and a great slaughter in the land of Edom.", "bbe": "The sword of the Lord is full of blood, it is fat with the best of the meat, with the blood of lambs and goats, with the best parts of the sheep: for the Lord has a feast in Bozrah, and much cattle will be put to death in the land of Edom.", "geneva": "The sword of the Lord is filled with blood: it is made fat with the fat and with the blood of the lambes and the goates, with the fat of the kidneis of the rams: for the Lord hath a sacrifice in Bozrah, and a great slaughter in the land of Edom.", "wycliffe": "The swerd of the Lord is fillid of blood, it is maad fat of the ynner fatnesse of the blood of lambren and of buckis of geet, of the blood of rammes ful of merow; for whi the slayn sacrifice of the Lord is in Bosra, and greet sleyng is in the lond of Edom.", "rotherham": "A sword, hath Yahweh—Glutted with blood Sated with fat,—With the blood of well-fed lambs and he-goats, With the fat of the kidneys of rams,—For, a sacrifice, hath Yahweh in Bozrah, Yea a great slaughter in the land of Edom;", "darby": "The sword of Jehovah is filled with blood, it is made fat with fatness, with the blood of lambs and goats, with the fat of the kidneys of rams; for Jehovah hath a sacrifice in Bozrah, and a great slaughter in the land of Edom.", "twenty": "", "jps": "The sword of HaShem is filled with blood, it is made fat with fatness, with the blood of lambs and goats, with the fat of the kidneys of rams; for HaShem hath a sacrifice in Bozrah, and a great slaughter in the land of Edom.", "acv": "The sword of Jehovah is filled with blood. It is made fat with fatness, with the blood of lambs and goats, with the fat of the kidneys of rams, for Jehovah has a sacrifice in Bozrah, and a great slaughter in the land of Edom.", "anderson": "", "haweis": "", "noyes": "The sword of Jehovah is full of blood; It is covered with fat, With the blood of lambs and goats, With the fat of the kidneys of rams; For Jehovah holdeth a sacrifice in Bozrah, And a great slaughter in the land of Edom.", "webster": "The sword of the LORD is filled with blood, it is made fat with fatness, [and] with the blood of lambs and goats, with the fat of the kidneys of rams: for the LORD hath a sacrifice in Bozrah, and a great slaughter in the land of Edom.", "vulgate": "gladius Domini repletus est sanguine incrassatus est adipe de sanguine agnorum et hircorum de sanguine medullatorum arietum victima enim Domini in Bosra et interfectio magna in terra Edom;", "brenton": "The sword of the Lord is filled with blood, it is glutted with fat, with the blood of goats and lambs, and with the fat of goats and rams: for the Lord has a sacrifice in Bosor, and a great slaughter in Idumea."}}, {"v": 7, "ref": "34:7", "o": "וְ/יָרְד֤וּ רְאֵמִים֙ עִמָּ֔/ם וּ/פָרִ֖ים עִם אַבִּירִ֑ים וְ/רִוְּתָ֤ה אַרְצָ/ם֙ מִ/דָּ֔ם וַ/עֲפָרָ֖/ם מֵ/חֵ֥לֶב יְדֻשָּֽׁן", "en": {"kjv": "And the unicorns shall come down with them, and the bullocks with the bulls; and their land shall be soaked with blood, and their dust made fat with fatness.", "web": "The wild oxen will come down with them, and the young bulls with the mighty bulls; and their land will be drunken with blood, and their dust made greasy with fat.", "bsb": "And the wild oxen will fall with them, the young bulls with the strong ones. Their land will be drenched with blood, and their soil will be soaked with fat.", "asv": "And the wild-oxen shall come down with them, and the bullocks with the bulls: and their land shall be drunken with blood, and their dust made fat with fatness.", "ylt": "And come down have reems with them, And bullocks with bulls, And soaked hath been their land from blood, And their dust from fatness is made fat.", "dra": "And the unicorns shall go down with them, and the bulls with the mighty: their land shall be soaked with blood, and their ground with the fat of fat ones.", "bbe": "And the strong oxen will go down to death together with the smaller cattle.", "geneva": "And the vnicorne shall come downe with them and the heiffers with the bulles, and their lande shalbe drunken with blood, and their dust made fat with fatnesse.", "wycliffe": "And vnycornes schulen go doun with hem, and bolis with hem that ben myyti; the lond of hem schal be fillid with blood, and the erthe of hem with ynnere fatnesse of fatte beestis;", "rotherham": "Then shall buffaloes come down with them, And bullocks with bulls,—So shall their land be soaked with blood, And, their dust, with fat, shall be enriched.", "darby": "And the buffaloes shall come down with them, and the bullocks with the bulls; and their land shall be soaked with blood, and their dust made fat with fatness.", "twenty": "", "jps": "And the wild-oxen shall come down with them, and the bullocks with the bulls; and their land shall be drunken with blood, and their dust made fat with fatness.", "acv": "And the wild oxen shall come down with them, and the bullocks with the bulls. And their land shall be drunken with blood, and their dust made fat with fatness.", "anderson": "", "haweis": "", "noyes": "The wild buffaloes shall fall down with them. And the bullocks with the bulls; The hind shall be drunk with blood, And the ground enriched with fat.", "webster": "And the unicorns shall come down with them, and the bullocks with the bulls; and their land shall be drenched with blood, and their dust made fat with fatness.", "vulgate": "et descendent unicornes cum eis et tauri cum potentibus inebriabitur terra eorum sanguine et humus eorum adipe pinguium;", "brenton": "And the mighty ones shall fall with them, and the rams and the bulls; and the land shall be soaked with blood, and shall be filled with their fat."}}, {"v": 8, "ref": "34:8", "o": "כִּ֛י י֥וֹם נָקָ֖ם לַֽ/יהוָ֑ה שְׁנַ֥ת שִׁלּוּמִ֖ים לְ/רִ֥יב צִיּֽוֹן", "en": {"kjv": "For it is the day of the Lord’s vengeance, and the year of recompences for the controversy of Zion.", "web": "For Yahweh has a day of vengeance, a year of recompense for the cause of Zion.", "bsb": "For the LORD has a day of vengeance, a year of recompense for the cause of Zion.", "asv": "For Jehovah hath a day of vengeance, a year of recompense for the cause of Zion.", "ylt": "(For a day of vengeance is to Jehovah, A year of recompences for Zion's strife,)", "dra": "For it is the day of the vengeance of the Lord, the year of recompenses of the judgment of Sion.", "bbe": "For it is the day of the Lord's punishment, when he gives payment for the wrongs done to Zion.", "geneva": "For it is the day of the Lordes vengeance, and the yeere of recompence for the iudgement of Zion.", "wycliffe": "for it is a dai of veniaunce of the Lord, a yeer of yeldyng of the dom of Sion.", "rotherham": "For a day of avenging, hath Yahweh,—A year of requitals for the quarrel of Zion.", "darby": "For it is the day of Jehovah's vengeance, the year of recompenses for the controversy of Zion.", "twenty": "", "jps": "For HaShem hath a day of vengeance, a year of recompense for the controversy of Zion.", "acv": "For Jehovah has a day of vengeance, a year of recompense for the cause of Zion.", "anderson": "", "haweis": "", "noyes": "For Jehovah holdeth a day of vengeance, A year of recompense in the cause of Zion.", "webster": "For [it is] the day of the LORD'S vengeance, [and] the year of recompenses for the controversy of Zion.", "vulgate": "quia dies ultionis Domini annus retributionum iudicii Sion;", "brenton": "For it is the day of judgment of the Lord, and the year of the recompence of Sion in judgment."}}, {"v": 9, "ref": "34:9", "o": "וְ/נֶהֶפְכ֤וּ נְחָלֶ֨י/הָ֙ לְ/זֶ֔פֶת וַ/עֲפָרָ֖/הּ לְ/גָפְרִ֑ית וְ/הָיְתָ֣ה אַרְצָ֔/הּ לְ/זֶ֖פֶת בֹּעֵרָֽה", "en": {"kjv": "And the streams thereof shall be turned into pitch, and the dust thereof into brimstone, and the land thereof shall become burning pitch.", "web": "Its streams will be turned into pitch, its dust into sulfur, And its land will become burning pitch.", "bsb": "Edom’s streams will be turned to tar, and her soil to sulfur; her land will become a blazing pitch.", "asv": "And the streams of Edom shall be turned into pitch, and the dust thereof into brimstone, and the land thereof shall become burning pitch.", "ylt": "And turned have been her streams to pitch, And her dust to brimstone, And her land hath become burning pitch.", "dra": "And the streams thereof shall be turned into pitch, and the ground thereof into brimstone: and the land thereof shall become burning pitch.", "bbe": "And its streams will be turned into boiling oil, and its dust into burning stone, and all the land will be on fire.", "geneva": "And the riuers thereof shall be turned into pitche, and the dust thereof into brimstone, and the land thereof shalbe burning pitch.", "wycliffe": "And the strondis therof schulen be turned in to pitche, and the erthe therof in to brymstoon; and the lond therof schal be in to brennyng pitch, niyt and dai.", "rotherham": "Then shall the torrents thereof be turned into pitch, And the dust thereof, into brimstone,—So shall her land become burning pitch:", "darby": "And the torrents thereof shall be turned into pitch, and its dust into brimstone; yea, the land thereof shall become burning pitch:", "twenty": "", "jps": "And the streams thereof shall be turned into pitch, and the dust thereof into brimstone, and the land thereof shall become burning pitch.", "acv": "And the streams of Edom shall be turned into pitch, and the dust of it into brimstone. And the land thereof shall become burning pitch.", "anderson": "", "haweis": "", "noyes": "Her streams shall be turned into pitch, And her dust into brimstone, And her whole land shall become burning pitch.", "webster": "And its streams shall be turned into pitch, and its dust into brimstone, and its land shall become burning pitch.", "vulgate": "et convertentur torrentes eius in picem et humus eius in sulphur et erit terra eius in picem ardentem;", "brenton": "And her valleys shall be turned into pitch, and her land into sulphur; and her land shall be as pitch burning night and day;"}}, {"v": 10, "ref": "34:10", "o": "לַ֤יְלָה וְ/יוֹמָם֙ לֹ֣א תִכְבֶּ֔ה לְ/עוֹלָ֖ם יַעֲלֶ֣ה עֲשָׁנָ֑/הּ מִ/דּ֤וֹר לָ/דוֹר֙ תֶּחֱרָ֔ב לְ/נֵ֣צַח נְצָחִ֔ים אֵ֥ין עֹבֵ֖ר בָּֽ/הּ", "en": {"kjv": "It shall not be quenched night nor day; the smoke thereof shall go up for ever: from generation to generation it shall lie waste; none shall pass through it for ever and ever.", "web": "It won’t be quenched night nor day. Its smoke will go up forever. From generation to generation, it will lie waste. No one will pass through it forever and ever.", "bsb": "It will not be quenched—day or night. Its smoke will ascend forever. From generation to generation it will lie desolate; no one will ever again pass through it.", "asv": "It shall not be quenched night nor day; the smoke thereof shall go up for ever; from generation to generation it shall lie waste; none shall pass through it for ever and ever.", "ylt": "By night and by day she is not quenched, To the age go up doth her smoke, From generation to generation she is waste, For ever and ever, none is passing into her.", "dra": "Night and day it shall not be quenched, the smoke thereof shall go up for ever: from generation to generation it shall lie waste, none shall pass through it for ever and ever.", "bbe": "It will not be put out day or night; its smoke will go up for ever: it will be waste from generation to generation; no one will go through it for ever.", "geneva": "It shall not be quenched night nor day: the smoke thereof shall goe vp euermore: it shall be desolate from generation to generation: none shall passe through it for euer.", "wycliffe": "It schal not be quenchid withouten ende, the smoke therof schal stie fro generacioun in to generacioun, and it schal be desolat in to worldis of worldis; noon schal passe therbi.", "rotherham": "Neither night nor day, shall it be quenched, To times age-abiding, shall ascend the smoke thereof,—From generation to generation, shall it be waste, Never, never, shall any pass through it:", "darby": "it shall not be quenched night nor day; the smoke thereof shall go up for ever: from generation to generation it shall lie waste; none shall pass through it for ever and ever.", "twenty": "", "jps": "It shall not be quenched night nor day, the smoke thereof shall go up for ever; from generation to generation it shall lie waste: none shall pass through it for ever and ever.", "acv": "It shall not be quenched night nor day. The smoke of it shall go up forever. From generation to generation it shall lie waste. None shall pass through it forever and ever.", "anderson": "", "haweis": "", "noyes": "Day and night it shall not be quenched; Its smoke shall ascend forever; From generation to generation it shall lie waste; None shall pass through it for ever and ever.", "webster": "It shall not be quenched night nor day; the smoke of it shall ascend for ever: from generation to generation it shall lie waste; none shall pass through it for ever and ever.", "vulgate": "nocte et die non extinguetur in sempiternum ascendet fumus eius a generatione in generationem desolabitur in saeculum saeculorum non erit transiens per eam;", "brenton": "and it shall never be quenched, and her smoke shall go up: it shall be made desolate throughout her generations,"}}, {"v": 11, "ref": "34:11", "o": "וִ/ירֵשׁ֨וּ/הָ֙ קָאַ֣ת וְ/קִפּ֔וֹד וְ/יַנְשׁ֥וֹף וְ/עֹרֵ֖ב יִשְׁכְּנוּ בָ֑/הּ וְ/נָטָ֥ה עָלֶ֛י/הָ קַֽו תֹ֖הוּ וְ/אַבְנֵי בֹֽהוּ", "en": {"kjv": "But the cormorant and the bittern shall possess it; the owl also and the raven shall dwell in it: and he shall stretch out upon it the line of confusion, and the stones of emptiness.", "web": "But the pelican and the porcupine will possess it. The owl and the raven will dwell in it. He will stretch the line of confusion over it, and the plumb line of emptiness.", "bsb": "The desert owl and screech owl will possess it, and the great owl and raven will dwell in it. The LORD will stretch out over Edom a measuring line of chaos and a plumb line of destruction.", "asv": "But the pelican and the porcupine shall possess it; and the owl and the raven shall dwell therein: and he will stretch over it the line of confusion, and the plummet of emptiness.", "ylt": "And possess her do pelican and hedge-hog, And owl and raven dwell in her, And He hath stretched out over her A line of vacancy, and stones of emptiness.", "dra": "The bittern and ericius shall possess it: and the ibis and the raven shall dwell in it: and a line shall be stretched out upon it, to bring it to nothing, and a plummet, unto desolation.", "bbe": "But the birds of the waste land will have their place there; it will be a heritage for the bittern and the raven: and it will be measured out with line and weight as a waste land.", "geneva": "But the pelicane and the hedgehog shall possesse it, and the great owle, and the rauen shall dwel in it, and he shall stretch out vpon it the line of vanitie, and the stones of emptinesse.", "wycliffe": "And onocrotalus, and an irchoun schulen welde it; and a capret, and a crowe schulen dwelle therynne; and a mesure schal be stretchid forth theronne, that it be dryuun to nouyt, and an hangynge plomet in to desolacyoun.", "rotherham": "That the vomiting pelican and the bittern may possess it: And the great owl and the raven, dwell therein; Then will he stretch out over it The line of desolation, and The plummet of emptiness.", "darby": "And the pelican and the bittern shall possess it, and the great owl and the raven shall dwell in it. And he shall stretch out upon it the line of waste, and the plummets of emptiness.", "twenty": "", "jps": "But the pelican and the bittern shall possess it, and the owl and the raven shall dwell therein; and He shall stretch over it the line of confusion, and the plummet of emptiness.", "acv": "But the pelican and the porcupine shall possess it. And the owl and the raven shall dwell in it. And he will stretch over it the line of confusion, and the plummet of emptiness.", "anderson": "", "haweis": "", "noyes": "The pelican and the hedgehog shall possess it; The heron and the raven shall dwell in it; Over it will he draw the measuring-line of destruction. And the plummet of desolation.", "webster": "But the cormorant and the bittern shall possess it; the owl also and the raven shall dwell in it: and he shall stretch out upon it the line of confusion, and the stones of emptiness.", "vulgate": "et possidebunt illam onocrotalus et ericius et ibis et corvus habitabunt in ea et extendetur super eam mensura ut redigatur ad nihilum et perpendiculum in desolationem;", "brenton": "and for a long time birds and hedgehogs, and ibises and ravens shall dwell in it: and the measuring line of desolation shall be cast over it, and satyrs shall dwell in it."}}, {"v": 12, "ref": "34:12", "o": "חֹרֶ֥י/הָ וְ/אֵֽין שָׁ֖ם מְלוּכָ֣ה יִקְרָ֑אוּ וְ/כָל שָׂרֶ֖י/הָ יִ֥הְיוּ אָֽפֶס", "en": {"kjv": "They shall call the nobles thereof to the kingdom, but none shall be there, and all her princes shall be nothing.", "web": "They shall call its nobles to the kingdom, but none shall be there; and all its princes shall be nothing.", "bsb": "No nobles will be left to proclaim a king, and all her princes will come to nothing.", "asv": "They shall call the nobles thereof to the kingdom, but none shall be there; and all its princes shall be nothing.", "ylt": "To the kingdom her freemen they call, But there are none there, And all her princes are at an end.", "dra": "The nobles thereof shall not be there: they shall call rather upon the king, and all the princes thereof shall be nothing.", "bbe": "The jackals will be there, and her great ones will be gone; they will say, There is no longer a kingdom there, and all her chiefs will have come to an end.", "geneva": "The nobles thereof shall call to the kingdome, and there shalbe none, and all the princes thereof shalbe as nothing.", "wycliffe": "The noble men therof schulen not be there; rathere thei schulen clepe the kyng in to help, and alle the princes therof schulen be in to nouyt.", "rotherham": "Her nobles (but none, are, there)! unto royalty, will call,—All, all her princes, shall become nought.", "darby": "Of her nobles who should proclaim the kingdom, none are there; and all her princes shall be nought.", "twenty": "", "jps": "As for her nobles, none shall be there to be called to the kingdom; and all her princes shall be nothing.", "acv": "They shall call the nobles of it to the kingdom, but none shall be there. And all its rulers shall be nothing.", "anderson": "", "haweis": "", "noyes": "Her nobles—none are there, who may proclaim a kingdom, And all her princes have come to naught.", "webster": "They shall call her nobles to the kingdom, but none [shall be] there, and all her princes shall be nothing.", "vulgate": "nobiles eius non erunt ibi regem potius invocabunt et omnes principes eius erunt in nihilum;", "brenton": "Her princes shall be no more; for her kings and her great men shall be destroyed."}}, {"v": 13, "ref": "34:13", "o": "וְ/עָלְתָ֤ה אַרְמְנֹתֶ֨י/הָ֙ סִירִ֔ים קִמּ֥וֹשׂ וָ/ח֖וֹחַ בְּ/מִבְצָרֶ֑י/הָ וְ/הָיְתָה֙ נְוֵ֣ה תַנִּ֔ים חָצִ֖יר לִ/בְנ֥וֹת יַעֲנָֽה", "en": {"kjv": "And thorns shall come up in her palaces, nettles and brambles in the fortresses thereof: and it shall be an habitation of dragons, and a court for owls.", "web": "Thorns will come up in its palaces, nettles and thistles in its fortresses; and it will be a habitation of jackals, a court for ostriches.", "bsb": "Her towers will be overgrown with thorns, her fortresses with thistles and briers. She will become a haunt for jackals, an abode for ostriches.", "asv": "And thorns shall come up in its palaces, nettles and thistles in the fortresses thereof; and it shall be a habitation of jackals, a court for ostriches.", "ylt": "And gone up her palaces have thorns, Nettle and bramble are in her fortresses, And it hath been a habitation of dragons, A court for daughters of an ostrich.", "dra": "And thorns and nettles shall grow up in its houses, and the thistle in the fortresses thereof: and it shall be the habitation of dragons, and the pasture of ostriches.", "bbe": "And thorns will come up in her fair houses, and waste plants in her strong towers: and foxes will make their holes there, and it will be a meeting-place for ostriches.", "geneva": "And it shall bring foorth thornes in the palaces thereof, nettles and thistles in the strong holdes thereof, and it shall be an habitation for dragons, and a court for ostriches.", "wycliffe": "And thornes and nettlis schulen growe in the housis therof, and a tasil in the strengthis therof; and it schal be the couche of dragouns, and the lesewe of ostrichis.", "rotherham": "Then shall come up, in her palaces thorns Nettles and thistles in her fortresses,—And she shall become A home for wild dogs, An enclosure for ostriches;", "darby": "And thorns shall come up in her palaces, nettles and brambles in her fortresses; and it shall be a dwelling-place of wild dogs, a court for ostriches.", "twenty": "", "jps": "And thorns shall come up in her palaces, nettles and thistles in the fortresses thereof; and it shall be a habitation of wild-dogs, an enclosure for ostriches.", "acv": "And thorns shall come up in its palaces, nettles and thistles in the fortresses of it. And it shall be a habitation of jackals, a court for ostriches.", "anderson": "", "haweis": "", "noyes": "Thorns shall spring up in her palaces; Nettles and thistles in her strongholds. She shall become a habitation for jackals, A court for ostriches.", "webster": "And thorns shall come up in her palaces, nettles and brambles in her fortresses, and it shall be a habitation of dragons, [and] a court for owls.", "vulgate": "et orientur in domibus eius spinae et urticae et paliurus in munitionibus eius et erit cubile draconum et pascua strutionum;", "brenton": "And thorns shall spring up in their cities, and in her strong holds: and they shall be habitations of monsters, and a court of ostriches."}}, {"v": 14, "ref": "34:14", "o": "וּ/פָגְשׁ֤וּ צִיִּים֙ אֶת אִיִּ֔ים וְ/שָׂעִ֖יר עַל רֵעֵ֣/הוּ יִקְרָ֑א אַךְ שָׁם֙ הִרְגִּ֣יעָה לִּילִ֔ית וּ/מָצְאָ֥ה לָ֖/הּ מָנֽוֹחַ", "en": {"kjv": "The wild beasts of the desert shall also meet with the wild beasts of the island, and the satyr shall cry to his fellow; the screech owl also shall rest there, and find for herself a place of rest.", "web": "The wild animals of the desert will meet with the wolves, and the wild goat will cry to his fellow. Yes, the night creature shall settle there, and shall find herself a place of rest.", "bsb": "The desert creatures will meet with hyenas, and one wild goat will call to another. There the night creature will settle and find her place of repose.", "asv": "And the wild beasts of the desert shall meet with the wolves, and the wild goat shall cry to his fellow; yea, the night-monster shall settle there, and shall find her a place of rest.", "ylt": "And met have Ziim with Aiim, And the goat for its companion calleth, Only there rested hath the night-owl, And hath found for herself a place of rest.", "dra": "And demons and monsters shall meet, and the hairy ones shall cry out one to another, there hath the lamia lain down, and found rest for herself.", "bbe": "And the beasts of the waste places will come together with the jackals, and the evil spirits will be crying to one another, even the night-spirit will come and make her resting-place there.", "geneva": "There shall meete also Ziim and Iim, and the Satyre shall cry to his fellow, and the shricheowle shall rest there, and shall finde for her selfe a quiet dwelling.", "wycliffe": "And fendis, and wondurful beestis, lijk men in the hiyere part and lijk assis in the nethir part, and an heeri schulen meete; oon schal crie to an other.", "rotherham": "Then shall criers meet with howlers, And, the shaggy creature, unto his fellow, shall call,—Only, there, shall, the night-spectre, Make her settlement, And find for herself a place of rest:", "darby": "And there shall the beasts of the desert meet with the jackals, and the wild goat shall cry to his fellow; the lilith also shall settle there, and find for herself a place of rest.", "twenty": "", "jps": "And the wild-cats shall meet with the jackals, and the satyr shall cry to his fellow; yea, the night-monster shall repose there, and shall find her a place of rest.", "acv": "And the wild beasts of the desert shall meet with the wolves. And the wild goat shall cry to his fellow. Yea, the screech owl shall settle there, and shall find her a place of rest.", "anderson": "", "haweis": "", "noyes": "The wild-cats shall fall upon the wolves, And the satyr shall call to his fellow; There also shall the night-spectre light, And find a place of rest.", "webster": "The wild beasts of the desert shall also meet with the wild beasts of the isle, and the satyr shall cry to his fellow; the screech-owl also shall rest there, and find for herself a place of rest.", "vulgate": "et occurrent daemonia onocentauris et pilosus clamabit alter ad alterum ibi cubavit lamia et invenit sibi requiem;", "brenton": "And devils shall meet with satyrs, and they shall cry one to the other: there shall satyrs rest, having found for themselves a place of rest."}}, {"v": 15, "ref": "34:15", "o": "שָׁ֣מָּ/ה קִנְּנָ֤ה קִפּוֹז֙ וַ/תְּמַלֵּ֔ט וּ/בָקְעָ֖ה וְ/דָגְרָ֣ה בְ/צִלָּ֑/הּ אַךְ שָׁ֛ם נִקְבְּצ֥וּ דַיּ֖וֹת אִשָּׁ֥ה רְעוּתָֽ/הּ", "en": {"kjv": "There shall the great owl make her nest, and lay, and hatch, and gather under her shadow: there shall the vultures also be gathered, every one with her mate.", "web": "The arrow snake will make her nest there, and lay, hatch, and gather under her shade. Yes, the kites will be gathered there, every one with her mate.", "bsb": "There the owl will make her nest; she will lay and hatch her eggs and gather her brood under her shadow. Even there the birds of prey will gather, each with its mate.", "asv": "There shall the dart-snake make her nest, and lay, and hatch, and gather under her shade; yea, there shall the kites be gathered, every one with her mate.", "ylt": "There made her nest hath the bittern, Yea, she layeth, and hath hatched, And hath gathered under her shadow, Only there gathered have been vultures, Each with its companion.", "dra": "There hath the ericius had its hole, and brought up its young ones, and hath dug round about, and cherished them in the shadow thereof: thither are the kites gathered together one to another.", "bbe": "The arrowsnake will make her hole and put her eggs there, and get her young together under her shade: there the hawks will come together by twos.", "geneva": "There shall the owle make her nest, and laye, and hatche, and gather them vnder her shadowe: there shall the vultures also bee gathered, euery one with her make.", "wycliffe": "Lamya schal ligge there, and foond rest there to hir silf; there an irchoun hadde dichis, and nurschide out whelpis, and diggide aboute, and fostride in the schadewe therof; there kitis weren gaderid togidere, oon to another.", "rotherham": "There, shall, the arrow-snake, Make her nest and lay, And hatch and gather under her shadow,—Only, there, shall be gathered the falcons, every one with her mate.", "darby": "There shall the arrow-snake make her nest, and lay, and hatch, and gather under her shadow; there also shall the vultures be gathered one with another.", "twenty": "", "jps": "There shall the arrowsnake make her nest, and lay, and hatch, and brood under her shadow; yea, there shall the kites be gathered, every one with her mate.", "acv": "There the dart-snake shall make her nest, and lay, and hatch, and gather under her shade. Yea, there the vultures shall be gathered, each one with her mate.", "anderson": "", "haweis": "", "noyes": "There also shall the arrow-snake make her nest, and lay her eggs; She shall hatch them, and gather her young under her shadow: There also shall the vultures be gathered together, Every one with her mate.", "webster": "There shall the great owl make her nest, and lay, and hatch, and gather under her shadow: there shall the vultures also be gathered, every one with her mate.", "vulgate": "ibi habuit foveam ericius et enutrivit catulos et circumfodit et fovit in umbra eius illuc congregati sunt milvi alter ad alterum;", "brenton": "There has the hedgehog made its nest, and the earth has safely preserved its young: there have the deer met, and seen one another's faces."}}, {"v": 16, "ref": "34:16", "o": "דִּרְשׁ֨וּ מֵֽ/עַל סֵ֤פֶר יְהוָה֙ וּֽ/קְרָ֔אוּ אַחַ֤ת מֵ/הֵ֨נָּה֙ לֹ֣א נֶעְדָּ֔רָה אִשָּׁ֥ה רְעוּתָ֖/הּ לֹ֣א פָקָ֑דוּ כִּֽי פִ/י֙ ה֣וּא צִוָּ֔ה וְ/רוּח֖/וֹ ה֥וּא קִבְּצָֽ/ן", "en": {"kjv": "Seek ye out of the book of the Lord, and read: no one of these shall fail, none shall want her mate: for my mouth it hath commanded, and his spirit it hath gathered them.", "web": "Search in the book of Yahweh, and read: not one of these will be missing. none will lack her mate. For my mouth has commanded, and his Spirit has gathered them.", "bsb": "Search and read the scroll of the LORD: Not one of these will go missing, not one will lack her mate, because He has ordered it by His mouth, and He will gather them by His Spirit.", "asv": "Seek ye out of the book of Jehovah, and read: no one of these shall be missing, none shall want her mate; for my mouth, it hath commanded, and his Spirit, it hath gathered them.", "ylt": "Seek out of the book of Jehovah, and read, One of these hath not been lacking, None hath missed its companion, For My mouth--it hath commanded, And His spirit--He hath gathered them.", "dra": "Search ye diligently in the book of the Lord, and read: not one of them was wanting, one hath not sought for the other: for that which proceedeth out of my mouth, he hath commanded, and his spirit it hath gathered them.", "bbe": "See what is recorded in the book of the Lord: all these will be there, not one without the other: the mouth of the Lord has given the order, and his spirit has made them come together.", "geneva": "Seeke in the booke of the Lord, and reade: none of these shall fayle, none shall want her make: for his mouth hath commanded, and his very Spirit hath gathered them.", "wycliffe": "Seke ye diligentli in the book of the Lord, and rede ye; oon of tho thingis failide not, oon souyte not another; for he comaundide that thing, that goith forth of my mouth, and his spirit he gaderide tho togidere.", "rotherham": "Seek ye out of the scroll of Yahweh, and read, Not, one from among them, is lacking, None, hath missed, her mate,—For, a mouth, hath, itself commanded, And, his spirit, hath itself gathered them:", "darby": "Search ye in the book of Jehovah and read: not one of these shall fail, one shall not have to seek for the other; for my mouth, it hath commanded, and his Spirit, it hath gathered them.", "twenty": "", "jps": "Seek ye out of the book of HaShem, and read; no one of these shall be missing, none shall want her mate; for My mouth it hath commanded, and the breath thereof it hath gathered them.", "acv": "Seek ye out of the book of Jehovah, and read. No one of these shall be missing. None shall want her mate. For my mouth, it has commanded, and his Spirit, it has gathered them.", "anderson": "", "haweis": "", "noyes": "Search ye the book of Jehovah, and read! Not one of these shall fail; Not one shall want her mate; For His mouth, it shall command, And His spirit, it shall gather them.", "webster": "Seek ye out of the book of the LORD, and read: no one of these shall fail, none shall want her mate: for my mouth it hath commanded, and his spirit it hath gathered them.", "vulgate": "requirite diligenter in libro Domini et legite unum ex eis non defuit alter ad alterum non quaesivit quia quod ex ore meo procedit ille mandavit et spiritus eius ipse congregavit ea;", "brenton": "They passed by in full number, and not one of them perished: they sought not one another; for the Lord commanded them, and his Spirit gathered them."}}, {"v": 17, "ref": "34:17", "o": "וְ/הֽוּא הִפִּ֤יל לָ/הֶן֙ גּוֹרָ֔ל וְ/יָד֛/וֹ חִלְּקַ֥תָּ/ה לָ/הֶ֖ם בַּ/קָּ֑ו עַד עוֹלָם֙ יִֽירָשׁ֔וּ/הָ לְ/ד֥וֹר וָ/ד֖וֹר יִשְׁכְּנוּ בָֽ/הּ", "en": {"kjv": "And he hath cast the lot for them, and his hand hath divided it unto them by line: they shall possess it for ever, from generation to generation shall they dwell therein.", "web": "He has cast the lot for them, and his hand has divided it to them with a measuring line. They shall possess it forever. From generation to generation they will dwell in it.", "bsb": "He has allotted their portion; His hand has distributed it by measure. They will possess it forever; they will dwell in it from generation to generation.", "asv": "And he hath cast the lot for them, and his hand hath divided it unto them by line: they shall possess it for ever; from generation to generation shall they dwell therein.", "ylt": "And He hath cast for them a lot, And His hand hath apportioned it to them by line, Unto the age they possess it, To all generations they dwell in it!", "dra": "And he hath cast the lot for them, and his hand hath divided it to them by line: they shall possess it for ever, from generation to generation they shall dwell therein.", "bbe": "And he has given them their heritage, and by his hand it has been measured out to them: it will be theirs for ever, their resting-place from generation to generation.", "geneva": "And he hath cast the lot for them, and his hand hath deuided it vnto them by line: they shall possesse it for euer: from generation to generation shall they dwell in it.", "wycliffe": "And he sente to hem eritage, and his hond departide it in mesure; til in to withouten ende tho schulen welde that lond, in generacioun and in to generacioun tho schulen dwelle ther ynne.", "rotherham": "Yea he himself, hath cast for them a lot, And his own hand, hath given to them a portion by line,—Unto times age-abiding, shall they possess it, To generation after generation, shall they dwell therein.", "darby": "For he himself hath cast the lot for them, and his hand hath divided it unto them with the line: they shall possess it for ever; from generation to generation shall they dwell therein.", "twenty": "", "jps": "And He hath cast the lot for them, and His hand hath divided it unto them by line; they shall possess it for ever, from generation to generation shall they dwell therein.", "acv": "And he has cast the lot for them, and his hand has divided it to them by line. They shall possess it forever. From generation to generation they shall dwell therein.", "anderson": "", "haweis": "", "noyes": "He shall cast the lot for them; His hand shall divide it for them with a line; They shall possess it forever; From generation to generation shall they dwell therein.", "webster": "And he hath cast the lot for them, and his hand hath divided it to them by line: they shall possess it for ever, from generation to generation shall they dwell therein.", "vulgate": "et ipse misit eis sortem et manus eius divisit eam illis in mensuram usque in aeternum possidebunt eam in generatione et generatione habitabunt in ea;", "brenton": "And he shall cast lots for them, and his hand has portioned out their pasture, saying, Ye shall inherit the land for ever: they shall rest on it through all generations."}}]}, {"c": 35, "verses": [{"v": 1, "ref": "35:1", "o": "יְשֻׂשׂ֥וּ/ם מִדְבָּ֖ר וְ/צִיָּ֑ה וְ/תָגֵ֧ל עֲרָבָ֛ה וְ/תִפְרַ֖ח כַּ/חֲבַצָּֽלֶת", "en": {"kjv": "The wilderness and the solitary place shall be glad for them; and the desert shall rejoice, and blossom as the rose.", "web": "The wilderness and the dry land will be glad. The desert will rejoice and blossom like a rose.", "bsb": "The wilderness and the land will be glad; the desert will rejoice and blossom like a rose.", "asv": "The wilderness and the dry land shall be glad; and the desert shall rejoice, and blossom as the rose.", "ylt": "They joy from the wilderness and dry place, And rejoice doth the desert, and flourish as the rose,", "dra": "The land that was desolate and impassable shall be glad, and the wilderness shall rejoice, and shall flourish like the lily.", "bbe": "The waste land and the dry places will be glad; the lowland will have joy and be full of flowers.", "geneva": "The desert and the wildernes shall reioyce: and the waste ground shalbe glad and florish as the rose.", "wycliffe": "The forsakun Judee and with outen weie schal be glad, and wildirnesse schal make ful out ioye, and schal floure as a lilie.", "rotherham": "Wilderness and parched land, shall be glad for them,—And the waste plain, shall exult, and blossom as the lily:", "darby": "The wilderness and the dry land shall be gladdened; and the desert shall rejoice, and blossom as the rose.", "twenty": "", "jps": "The wilderness and the parched land shall be glad; and the desert shall rejoice, and blossom as the rose.", "acv": "The wilderness and the dry land shall be glad. And the desert shall rejoice, and blossom as the rose.", "anderson": "", "haweis": "", "noyes": "The wilderness and the parched land shall be glad, And the desert rejoice and blossom as the rose;", "webster": "The wilderness and the solitary place shall be glad for them; and the desert shall rejoice and blossom as the rose.", "vulgate": "laetabitur deserta et invia et exultabit solitudo et florebit quasi lilium;", "brenton": "Be glad, thou thirsty desert: let the wilderness exult, and flower as the lily."}}, {"v": 2, "ref": "35:2", "o": "פָּרֹ֨חַ תִּפְרַ֜ח וְ/תָגֵ֗ל אַ֚ף גִּילַ֣ת וְ/רַנֵּ֔ן כְּב֤וֹד הַ/לְּבָנוֹן֙ נִתַּן לָ֔/הּ הֲדַ֥ר הַ/כַּרְמֶ֖ל וְ/הַ/שָּׁר֑וֹן הֵ֛מָּה יִרְא֥וּ כְבוֹד יְהוָ֖ה הֲדַ֥ר אֱלֹהֵֽי/נוּ", "en": {"kjv": "It shall blossom abundantly, and rejoice even with joy and singing: the glory of Lebanon shall be given unto it, the excellency of Carmel and Sharon, they shall see the glory of the Lord, and the excellency of our God.", "web": "It will blossom abundantly, and rejoice even with joy and singing. Lebanon’s glory will be given to it, the excellence of Carmel and Sharon. They will see Yahweh’s glory, the excellence of our God.", "bsb": "It will bloom profusely and rejoice with joy and singing. The glory of Lebanon will be given to it, the splendor of Carmel and Sharon. They will see the glory of the LORD, the splendor of our God.", "asv": "It shall blossom abundantly, and rejoice even with joy and singing; the glory of Lebanon shall be given unto it, the excellency of Carmel and Sharon: they shall see the glory of Jehovah, the excellency of our God.", "ylt": "Flourishing it doth flourish, and rejoice, Yea, with joy and singing, The honour of Lebanon hath been given to it, The beauty of Carmel and Sharon, They--they see the honour of Jehovah, The majesty of our God.", "dra": "It shall bud forth and blossom, and shall rejoice with joy and praise: the glory of Libanus is given to it: the beauty of Carmel, and Saron, they shall see the glory of the Lord, and the beauty of our God.", "bbe": "It will be flowering like the rose; it will be full of delight and songs; the glory of Lebanon will be given to it; the pride of Carmel and Sharon: they will see the glory of the Lord, the power of our God.", "geneva": "It shall florish abundantly and shall greatly reioyce also and ioye: the glory of Lebanon shalbe giuen vnto it: the beautie of Carmel, and of Sharon, they shall see the glory of the Lord, and the excellencie of our God.", "wycliffe": "It buriownynge schal buriowne, and it glad and preisynge schal make ful out ioie. The glorie of Liban is youun to it, the fairnesse of Carmele and of Saron; thei schulen se the glorie of the Lord, and the fairnesse of oure God.", "rotherham": "It shall, blossom abundantly, and exult, Yea with exultation and shouts of triumph, The glory of Lebanon, hath been given to it, The splendour of Carmel, and Sharon,—They, shall see the glory of Yahweh, the splendour of our God.", "darby": "It shall blossom abundantly and rejoice even with joy and shouting: the glory of Lebanon shall be given unto it, the excellency of Carmel and Sharon. They shall see the glory of Jehovah, the excellency of ourGod.", "twenty": "", "jps": "It shall blossom abundantly, and rejoice, even with joy and singing; the glory of Lebanon shall be given unto it, the excellency of Carmel and Sharon; they shall see the glory of HaShem, the excellency of our G-d.", "acv": "It shall blossom abundantly, and rejoice even with joy and singing. The glory of Lebanon shall be given to it, the excellency of Carmel and Sharon. They shall see the glory of Jehovah, the excellency of our God.", "anderson": "", "haweis": "", "noyes": "It shall blossom abundantly, and exult with joy and singing; The glory of Lebanon shall be given to it; The beauty of Carmel and Sharon; They shall behold the glory of Jehovah, The majesty of our God;", "webster": "It shall blossom abundantly, and rejoice, even with joy and singing: the glory of Lebanon shall be given to it, the excellence of Carmel and Sharon, they shall see the glory of the LORD, [and] the excellence of our God.", "vulgate": "germinans germinabit et exultabit laetabunda et laudans gloria Libani data est ei decor Carmeli et Saron ipsi videbunt gloriam Domini et decorem Dei nostri;", "brenton": "And the desert places of Jordan shall blossom and rejoice; the glory of Libanus has been given to it, and the honour of Carmel; and my people shall see the glory of the Lord, and the majesty of God."}}, {"v": 3, "ref": "35:3", "o": "חַזְּק֖וּ יָדַ֣יִם רָפ֑וֹת וּ/בִרְכַּ֥יִם כֹּשְׁל֖וֹת אַמֵּֽצוּ", "en": {"kjv": "Strengthen ye the weak hands, and confirm the feeble knees.", "web": "Strengthen the weak hands, and make firm the feeble knees.", "bsb": "Strengthen the limp hands and steady the feeble knees!", "asv": "Strengthen ye the weak hands, and confirm the feeble knees.", "ylt": "Strengthen ye the feeble hands, Yea, the stumbling knees strengthen.", "dra": "Strengthen ye the feeble hands, and confirm the weak knees.", "bbe": "Make strong the feeble hands, give support to the shaking knees.", "geneva": "Strengthen the weake handes, and comfort the feeble knees.", "wycliffe": "Coumforte ye comelid hondis, and make ye strong feble knees.", "rotherham": "Strengthen ye the weak hands,—The trembling knees, make ye firm:", "darby": "Strengthen the weak hands and confirm the tottering knees.", "twenty": "", "jps": "Strengthen ye the weak hands, and make firm the tottering knees.", "acv": "Strengthen ye the weak hands, and confirm the feeble knees.", "anderson": "", "haweis": "", "noyes": "Strengthen ye the weak hands, And confirm the tottering knees!", "webster": "Strengthen ye the weak hands, and confirm the feeble knees.", "vulgate": "confortate manus dissolutas et genua debilia roborate;", "brenton": "Be strong, ye relaxed hands and palsied knees."}}, {"v": 4, "ref": "35:4", "o": "אִמְרוּ֙ לְ/נִמְהֲרֵי לֵ֔ב חִזְק֖וּ אַל תִּירָ֑אוּ הִנֵּ֤ה אֱלֹֽהֵי/כֶם֙ נָקָ֣ם יָב֔וֹא גְּמ֣וּל אֱלֹהִ֔ים ה֥וּא יָב֖וֹא וְ/יֹשַׁעֲ/כֶֽם", "en": {"kjv": "Say to them that are of a fearful heart, Be strong, fear not: behold, your God will come with vengeance, even God with a recompence; he will come and save you.", "web": "Tell those who have a fearful heart, “Be strong. Don’t be afraid. Behold, your God will come with vengeance, God’s retribution. He will come and save you.", "bsb": "Say to those with anxious hearts: “Be strong, do not fear! Behold, your God will come with vengeance. With divine retribution He will come to save you.”", "asv": "Say to them that are of a fearful heart, Be strong, fear not: behold, your God will come with vengeance, with the recompense of God; he will come and save you.", "ylt": "Say to the hastened of heart, `Be strong, Fear not, lo, your God; vengeance cometh, The recompence of God, He Himself doth come and save you.'", "dra": "Say to the fainthearted: Take courage, and fear not: behold your God will bring the revenge of recompense: God himself will come and will save you.", "bbe": "Say to those who are full of fear, Be strong and take heart: see, your God will give punishment; the reward of God will come; he himself will come to be your saviour.", "geneva": "Say vnto them that are fearefull, Bee you strong, feare not: beholde, your God commeth with vengeance: euen God with a recompense, he will come and saue you.", "wycliffe": "Seie ye, Men of litil coumfort, be ye coumfortid, and nyle ye drede; lo! oure God schal brynge the veniaunce of yeldyng, God hym silf schal come, and schal saue vs.", "rotherham": "Say to the hurried in heart, Be strong, Do not fear,—Lo! your God, with avenging, doth come, With the recompence of God, He, doth come to save you.", "darby": "Say to them that are of a timid heart, Be strong, fear not; behold yourGod: vengeance cometh, the recompense ofGod! He will come himself, and save you.", "twenty": "", "jps": "Say to them that are of a fearful heart: 'Be strong, fear not'; behold, your G-d will come with vengeance, with the recompense of G-d He will come and save you.", "acv": "Say to those who are of a fearful heart, Be strong, fear not. Behold, your God will come with vengeance, with the recompense of God. He will come and save you.", "anderson": "", "haweis": "", "noyes": "Say ye to the faint-hearted, \"Be ye strong; fear ye not; Behold your God! Vengeance cometh, the retribution of God; He will come and save you!\"", "webster": "Say to them [that are] of a fearful heart, Be strong, fear not: behold, your God will come [with] vengeance, [even] God [with] a recompense; he will come and save you.", "vulgate": "dicite pusillanimis confortamini nolite timere ecce Deus vester ultionem adducet retributionis Deus ipse veniet et salvabit vos;", "brenton": "Comfort one another, ye fainthearted; be strong, fear not; behold, our God renders judgment, and he will render it; he will come and save us."}}, {"v": 5, "ref": "35:5", "o": "אָ֥ז תִּפָּקַ֖חְנָה עֵינֵ֣י עִוְרִ֑ים וְ/אָזְנֵ֥י חֵרְשִׁ֖ים תִּפָּתַֽחְנָה", "en": {"kjv": "Then the eyes of the blind shall be opened, and the ears of the deaf shall be unstopped.", "web": "Then the eyes of the blind will be opened, and the ears of the deaf will be unstopped.", "bsb": "Then the eyes of the blind will be opened and the ears of the deaf unstopped.", "asv": "Then the eyes of the blind shall be opened, and the ears of the deaf shall be unstopped.", "ylt": "Then opened are eyes of the blind, And ears of the deaf are unstopped,", "dra": "Then shall the eyes of the blind be opened, and the ears of the deaf shall be unstopped.", "bbe": "Then the eyes of the blind will see, and the ears which are stopped will be open.", "geneva": "Then shall the eyes of the blinde be lightened, and the eares of the deafe be opened.", "wycliffe": "Thanne the iyen of blynde men schulen be openyd, and the eeris of deef men schulen be opyn.", "rotherham": "Then, shall be opened the eyes of the blind,—And, the ears of the deaf, be unstopped:", "darby": "Then the eyes of the blind shall be opened, and the ears of the deaf be unstopped;", "twenty": "", "jps": "Then the eyes of the blind shall be opened, and the ears of the deaf shall be unstopped.", "acv": "Then the eyes of the blind shall be opened, and the ears of the deaf shall be unstopped.", "anderson": "", "haweis": "", "noyes": "Then shall the eyes of the blind be opened, And the ears of the deaf be unstopped.", "webster": "Then the eyes of the blind shall be opened, and the ears of the deaf shall be unstopped.", "vulgate": "tunc aperientur oculi caecorum et aures surdorum patebunt;", "brenton": "Then shall the eyes of the blind be opened, and the ears of the deaf shall hear."}}, {"v": 6, "ref": "35:6", "o": "אָ֣ז יְדַלֵּ֤ג כָּֽ/אַיָּל֙ פִּסֵּ֔חַ וְ/תָרֹ֖ן לְשׁ֣וֹן אִלֵּ֑ם כִּֽי נִבְקְע֤וּ בַ/מִּדְבָּר֙ מַ֔יִם וּ/נְחָלִ֖ים בָּ/עֲרָבָֽה", "en": {"kjv": "Then shall the lame man leap as an hart, and the tongue of the dumb sing: for in the wilderness shall waters break out, and streams in the desert.", "web": "Then the lame man will leap like a deer, and the tongue of the mute will sing; for waters will break out in the wilderness, and streams in the desert.", "bsb": "Then the lame will leap like a deer and the mute tongue will shout for joy. For waters will gush forth in the wilderness, and streams in the desert.", "asv": "Then shall the lame man leap as a hart, and the tongue of the dumb shall sing; for in the wilderness shall waters break out, and streams in the desert.", "ylt": "Then leap as a hart doth the lame, And sing doth the tongue of the dumb, For broken up in a wilderness have been waters, And streams in a desert.", "dra": "Then shall the lame man leap as a hart, and the tongue of the dumb shall be free: for waters are broken out in the desert, and streams in the wilderness.", "bbe": "Then will the feeble-footed be jumping like a roe, and the voice which was stopped will be loud in song: for in the waste land streams will be bursting out, and waters in the dry places.", "geneva": "Then shall ye lame man leape as an hart, and the dumme mans tongue shall sing: for in the wildernes shall waters breake out, and riuers in ye desert.", "wycliffe": "Thanne a crokid man schal skippe as an hert, and the tunge of doumbe men schal be openyd; for whi watris ben brokun out in desert, and stremes in wildirnesse.", "rotherham": "Then, shall leap as a hart the lame, Then shall shout the tongue of the dumb, For, there have broken forth—In the desert—waters, And streams, in the waste plain:", "darby": "then shall the lame [man] leap as a hart, and the tongue of the dumb sing: for in the wilderness shall waters break out, and torrents in the desert.", "twenty": "", "jps": "Then shall the lame man leap as a hart, and the tongue of the dumb shall sing; for in the wilderness shall waters break out, and streams in the desert.", "acv": "Then the lame man shall leap as a hart, and the tongue of the mute shall sing. For waters in the wilderness shall break out, and streams in the desert.", "anderson": "", "haweis": "", "noyes": "Then shall the lame leap like the hart, And the tongue of the dumb shall sing; For in the wilderness shall waters break forth, And streams in the desert.", "webster": "Then shall the lame [man] leap as a hart, and the tongue of the dumb shall sing: for in the wilderness shall waters break out, and streams in the desert.", "vulgate": "tunc saliet sicut cervus claudus et aperta erit lingua mutorum quia scissae sunt in deserto aquae et torrentes in solitudine;", "brenton": "Then shall the lame man leap as an hart, and the tongue of the stammerers shall speak plainly; for water has burst forth in the desert, and a channel of water in a thirsty land."}}, {"v": 7, "ref": "35:7", "o": "וְ/הָיָ֤ה הַ/שָּׁרָב֙ לַ/אֲגַ֔ם וְ/צִמָּא֖וֹן לְ/מַבּ֣וּעֵי מָ֑יִם בִּ/נְוֵ֤ה תַנִּים֙ רִבְצָ֔/הּ חָצִ֖יר לְ/קָנֶ֥ה וָ/גֹֽמֶא", "en": {"kjv": "And the parched ground shall become a pool, and the thirsty land springs of water: in the habitation of dragons, where each lay, shall be grass with reeds and rushes.", "web": "The burning sand will become a pool, and the thirsty ground springs of water. Grass with reeds and rushes will be in the habitation of jackals, where they lay.", "bsb": "The parched ground will become a pool, the thirsty land springs of water. In the haunt where jackals once lay, there will be grass and reeds and papyrus.", "asv": "And the glowing sand shall become a pool, and the thirsty ground springs of water: in the habitation of jackals, where they lay, shall be grass with reeds and rushes.", "ylt": "And the mirage hath become a pond, And the thirsty land fountains of waters, In the habitation of dragons, Its place of couching down, a court for reed and rush.", "dra": "And that which was dry land, shall become a pool, and the thirsty land springs of water. In the dens where dragons dwelt before, shall rise up the verdure of the reed and the bulrush.", "bbe": "And the burning sand will become a pool, and the dry earth springs of waters: the fields where the sheep take their food will become wet land, and water-plants will take the place of grass.", "geneva": "And the dry ground shalbe as a poole, and the thirstie (as springs of water in the habitation of dragons: where they lay) shall be a place for reedes and rushes.", "wycliffe": "And that that was drie, is maad in to a poond, and the thirsti is maad in to wellis of watris. Grenenesse of rehed, and of spier schal growe in dennes, in whiche dwelliden dragouns bifore. And a path and a weie schal be there,", "rotherham": "Then shall the glowing sand, become a lake, And thirsty ground—springs of water,—In the home of the wild dog—its lair, Shall be an enclosure for cane and paper—reed.", "darby": "And the mirage shall become a pool, and the thirsty land springs of water: in the habitation of wild dogs, where they lay down, shall be grass with reeds and rushes.", "twenty": "", "jps": "And the parched land shall become a pool, and the thirsty ground springs of water; in the habitation of jackals herds shall lie down, it shall be an enclosure for reeds and rushes.", "acv": "And the glowing sand shall become a pool, and the thirsty ground springs of water. In the habitation of jackals, where they lay, shall be grass with reeds and rushes.", "anderson": "", "haweis": "", "noyes": "The glowing sands shall become a pool, And the thirsty ground springs of water; In the habitation of jackals, where they lie, Shall be a place for reeds and rushes.", "webster": "And the parched ground shall become a pool, and the thirsty land springs of water: in the habitation of dragons, where each lay, [shall be] grass with reeds and rushes.", "vulgate": "et quae erat arida in stagnum et sitiens in fontes aquarum in cubilibus in quibus prius dracones habitabant orietur viror calami et iunci;", "brenton": "And the dry land shall become pools, and a fountain of water shall be poured into the thirsty land; there shall there be a joy of birds, ready habitations and marshes."}}, {"v": 8, "ref": "35:8", "o": "וְ/הָיָה שָׁ֞ם מַסְל֣וּל וָ/דֶ֗רֶךְ וְ/דֶ֤רֶךְ הַ/קֹּ֨דֶשׁ֙ יִקָּ֣רֵא לָ֔/הּ לֹֽא יַעַבְרֶ֥/נּוּ טָמֵ֖א וְ/הוּא לָ֑/מוֹ הֹלֵ֥ךְ דֶּ֛רֶךְ וֶ/אֱוִילִ֖ים לֹ֥א יִתְעֽוּ", "en": {"kjv": "And an highway shall be there, and a way, and it shall be called The way of holiness; the unclean shall not pass over it; but it shall be for those: the wayfaring men, though fools, shall not err therein.", "web": "A highway will be there, a road, and it will be called The Holy Way. The unclean shall not pass over it, but it will be for those who walk in the Way. Wicked fools will not go there.", "bsb": "And there will be a highway called the Way of Holiness. The unclean will not travel it— only those who walk in the Way— and fools will not stray onto it.", "asv": "And a highway shall be there, and a way, and it shall be called The way of holiness; the unclean shall not pass over it; but it shall be for the redeemed: the wayfaring men, yea fools, shall not err therein.", "ylt": "And a highway hath been there, and a way, And the `way of holiness' is called to it, Not pass over it doth the unclean, And He Himself is by them, Whoso is going in the way--even fools err not.", "dra": "And a path and a way shall be there, and it shall be called the holy way: the unclean shall not pass over it, and this shall be unto you a straight way, so that fools shall not err therein.", "bbe": "And a highway will be there; its name will be, The Holy Way; the unclean and the sinner may not go over it, and those who go on it will not be turned out of the way by the foolish.", "geneva": "And there shalbe a path and a way, and the way shalbe called holy: the polluted shall not passe by it: for he shalbe with them, and walke in the way, and the fooles shall not erre.", "wycliffe": "and it schal be clepid an hooli weie, he that is defoulid schal not passe therbi; and this schal be a streiyt weie to you, so that foolis erre not therbi.", "rotherham": "And there shall be there, a raised way—even a high road, And the Highroad of Holiness, shall it be called, There shall not pass over it one who is unclean; But He Himself, shall be one of them travelling the road, And the perverse, shall not stray [thereinto] .", "darby": "And a highway shall be there and a way, and it shall be called, The way of holiness: the unclean shall not pass through it; but it shall be for these. Those that go [this] way — even fools, — shall not err [therein].", "twenty": "", "jps": "And a highway shall be there, and a way, and it shall be called The way of holiness; the unclean shall not pass over it; but it shall be for those; the wayfaring men, yea fools, shall not err therein.", "acv": "And a highway shall be there, and a way. And it shall be called The way of holiness. The unclean shall not pass over it, but it shall be for the redeemed, the wayfaring men. Yea fools shall not err in it.", "anderson": "", "haweis": "", "noyes": "And a path shall be there, and a highway, And it shall be called the holy way; No unclean person shall pass over it; it shall be for them alone; He that therein goeth in this way, though a fool, shall not err therein.", "webster": "And a highway shall be there, and a way, and it shall be called, The way of holiness; the unclean shall not pass over it; but it [shall be] for those: the way-faring men, though fools, shall not err [therein].", "vulgate": "et erit ibi semita et via et via sancta vocabitur non transibit per eam pollutus et haec erit nobis directa via ita ut stulti non errent per eam;", "brenton": "There shall be there a pure way, and it shall be called a holy way; and there shall not pass by there any unclean person, neither shall there be there an unclean way; but the dispersed shall walk on it, and they shall not go astray."}}, {"v": 9, "ref": "35:9", "o": "לֹא יִהְיֶ֨ה שָׁ֜ם אַרְיֵ֗ה וּ/פְרִ֤יץ חַיּוֹת֙ בַּֽל יַעֲלֶ֔/נָּה לֹ֥א תִמָּצֵ֖א שָׁ֑ם וְ/הָלְכ֖וּ גְּאוּלִֽים", "en": {"kjv": "No lion shall be there, nor any ravenous beast shall go up thereon, it shall not be found there; but the redeemed shall walk there:", "web": "No lion will be there, nor will any ravenous animal go up on it. They will not be found there; but the redeemed will walk there.", "bsb": "No lion will be there, and no vicious beast will go up on it. Such will not be found there, but the redeemed will walk upon it.", "asv": "No lion shall be there, nor shall any ravenous beast go up thereon; they shall not be found there; but the redeemed shall walk there:", "ylt": "No lion is there, yea, a destructive beast Ascendeth it not, it is not found there, And walked have the redeemed,", "dra": "No lion shall be there, nor shall any mischievous beast go up by it, nor be found there: but they shall walk there that shall be delivered.", "bbe": "No lion will be there, or any cruel beast; they will not be seen there; but those for whom the Lord has given a price,", "geneva": "There shall be no lyon, nor noysome beastes shall ascend by it, neither shall they be found there, that the redeemed may walke.", "wycliffe": "A lioun schal not be there, and an yuel beeste schal not stie therbi, nether schal be foundun there.", "rotherham": "There shall be, there, no lion, Nor shall ravenous beast, go up thereon, It shall not be found, there,—Thus, shall travel the redeemed;", "darby": "No lion shall be there, nor shall ravenous beast go up thereon, nor be found there; but the redeemed shall walk [there].", "twenty": "", "jps": "No lion shall be there, nor shall any ravenous beast go up thereon, they shall not be found there; but the redeemed shall walk there;", "acv": "No lion shall be there, nor shall any ravenous beast go up in it. They shall not be found there, but the redeemed shall walk there.", "anderson": "", "haweis": "", "noyes": "No lion shall be there, Nor shall any ravenous beast go up thereon; It shall not be found there; But the redeemed shall walk there.", "webster": "No lion shall be there, nor [any] ravenous beast shall go up thereon, it shall not be found there; but the redeemed shall walk [there]:", "vulgate": "non erit ibi leo et mala bestia non ascendet per eam nec invenietur ibi et ambulabunt qui liberati fuerint;", "brenton": "And there shall be no lion there, neither shall any evil beast go up upon it, nor at all be found there; but the redeemed and gathered on the Lord's behalf, shall walk in it,"}}, {"v": 10, "ref": "35:10", "o": "וּ/פְדוּיֵ֨י יְהוָ֜ה יְשֻׁב֗וּ/ן וּ/בָ֤אוּ צִיּוֹן֙ בְּ/רִנָּ֔ה וְ/שִׂמְחַ֥ת עוֹלָ֖ם עַל רֹאשָׁ֑/ם שָׂשׂ֤וֹן וְ/שִׂמְחָה֙ יַשִּׂ֔יגוּ וְ/נָ֖סוּ יָג֥וֹן וַ/אֲנָחָֽה", "en": {"kjv": "And the ransomed of the Lord shall return, and come to Zion with songs and everlasting joy upon their heads: they shall obtain joy and gladness, and sorrow and sighing shall flee away.", "web": "The Yahweh’s ransomed ones will return, and come with singing to Zion; and everlasting joy will be on their heads. They will obtain gladness and joy, and sorrow and sighing will flee away.”", "bsb": "So the redeemed of the LORD will return and enter Zion with singing, crowned with everlasting joy. Gladness and joy will overtake them, and sorrow and sighing will flee.", "asv": "and the ransomed of Jehovah shall return, and come with singing unto Zion; and everlasting joy shall be upon their heads: they shall obtain gladness and joy, and sorrow and sighing shall flee away.", "ylt": "And the ransomed of Jehovah return, And have entered Zion with singing. And joy age-during on their head, Joy and gladness they attain, And fled away have sorrow and sighing!", "dra": "And the redeemed of the Lord shall return, and shall come into Sion with praise, and everlasting joy shall be upon their heads: they shall obtain joy and gladness, and sorrow and mourning shall flee away.", "bbe": "Even those whom he has made free, will come back again; they will come with songs to Zion; on their heads will be eternal joy; delight and joy will be theirs, and sorrow and sounds of grief will be gone for ever.", "geneva": "Therefore the redeemed of the Lord shall returne and come to Zion with prayse: and euerlasting ioy shall bee vpon their heads: they shall obteine ioye and gladnesse, and sorow and mourning shall flee away.", "wycliffe": "And thei schulen go, that ben delyuered and ayenbouyt of the Lord; and thei schulen be conuertid, and schulen come in to Sion with preisyng; and euerlastynge gladnesse schal be on the heed of hem; thei schulen haue ioie and gladnesse, and sorewe and weilyng schulen fle awei.", "rotherham": "And the ransomed of Yahweh! shall return, And shall enter Zion with shouting, With gladness age-abiding, upon their head, Joy and gladness shall overtake them, And sorrow and sighing, shall flee away.", "darby": "And the ransomed of Jehovah shall return, and come to Zion with singing; and everlasting joy shall be upon their heads: they shall obtain gladness and joy, and sorrow and sighing shall flee away.", "twenty": "", "jps": "And the ransomed of HaShem shall return, and come with singing unto Zion, and everlasting joy shall be upon their heads; they shall obtain gladness and joy, and sorrow and sighing shall flee away.", "acv": "And the ransomed of Jehovah shall return, and come with singing to Zion. And everlasting joy shall be upon their heads. They shall obtain gladness and joy. And sorrow and sighing shall flee away.", "anderson": "", "haweis": "", "noyes": "Yea, the ransomed of Jehovah shall return; They shall come to Zion with songs: Everlasting joy shall be upon their heads; They shall obtain joy and gladness, And sorrow and sighing shall flee away.", "webster": "And the ransomed of the LORD shall return, and come to Zion with songs and everlasting joy upon their heads: they shall obtain joy and gladness, and sorrow and sighing shall flee away.", "vulgate": "et redempti a Domino convertentur et venient in Sion cum laude et laetitia sempiterna super caput eorum gaudium et laetitiam obtinebunt et fugiet dolor et gemitus;", "brenton": "and shall return, and come to Sion with joy, and everlasting joy shall be over their head; for on their head shall be praise and exultation, and joy shall take possession of them: sorrow and pain, and groaning have fled away."}}]}, {"c": 36, "verses": [{"v": 1, "ref": "36:1", "o": "וַ/יְהִ֡י בְּ/אַרְבַּע֩ עֶשְׂרֵ֨ה שָׁנָ֜ה לַ/מֶּ֣לֶךְ חִזְקִיָּ֗הוּ עָלָ֞ה סַנְחֵרִ֤יב מֶֽלֶךְ אַשּׁוּר֙ עַ֣ל כָּל עָרֵ֧י יְהוּדָ֛ה הַ/בְּצֻר֖וֹת וַֽ/יִּתְפְּשֵֽׂ/ם", "en": {"kjv": "Now it came to pass in the fourteenth year of king Hezekiah, that Sennacherib king of Assyria came up against all the defenced cities of Judah, and took them.", "web": "Now in the fourteenth year of king Hezekiah, Sennacherib king of Assyria attacked all of the fortified cities of Judah, and captured them.", "bsb": "In the fourteenth year of Hezekiah’s reign, Sennacherib king of Assyria attacked and captured all the fortified cities of Judah.", "asv": "Now it came to pass in the fourteenth year of king Hezekiah, that Sennacherib king of Assyria came up against all the fortified cities of Judah, and took them.", "ylt": "And it cometh to pass, in the fourteenth year of king Hezekiah, come up hath Sennacherib king of Asshur against all the fenced cities of Judah, and seizeth them.", "dra": "And it came to pass in the fourteenth year of king Ezechias, that Sennacherib king of the Assyrians came up against all the fenced cities of Juda, and took them.", "bbe": "And it came about in the fourteenth year of King Hezekiah that Sennacherib, king of Assyria, came up against all the walled towns of Judah and took them.", "geneva": "Nowe in the fourteenth yeere of King Hezekiah, Saneherib King of Asshur came vp against al the strong cities of Iudah, and tooke them.", "wycliffe": "And it was don in the fourtenthe yeer of kyng Ezechie, Sennacherib, the kyng of Assiriens, stiede on alle the stronge citees of Juda, and took tho.", "rotherham": "Now it came to pass in the fourteenth year of King Hezekiah, that Sennacherib king of Assyria came up, against all the fortified cities of Judah and took them.", "darby": "And it came to pass in the fourteenth year of king Hezekiah, that Sennacherib king of Assyria came up against all the fortified cities of Judah, and took them.", "twenty": "", "jps": "Now it came to pass in the fourteenth year of king Hezekiah, that Sennacherib king of Assyria came up against all the fortified cities of Judah, and took them.", "acv": "Now it came to pass in the fourteenth year of king Hezekiah, that Sennacherib king of Assyria came up against all the fortified cities of Judah, and took them.", "anderson": "", "haweis": "", "noyes": "In the fourteenth year of King Hezekiah, Sennacherib, king of Assyria, came up against all the fortified cities of Judah, and took them.", "webster": "Now it came to pass in the fourteenth year of king Hezekiah, [that] Sennacherib king of Assyria came up against all the fortified cities of Judah, and took them.", "vulgate": "et factum est in quartodecimo anno regis Ezechiae ascendit Sennacherib rex Assyriorum super omnes civitates Iuda munitas et cepit eas;", "brenton": "Now it came to pass in the fourteenth year of the reign of Ezekias, that Sennacherim, king of the Assyrians, came up against the strong cities of Judea, and took them."}}, {"v": 2, "ref": "36:2", "o": "וַ/יִּשְׁלַ֣ח מֶֽלֶךְ אַשּׁ֣וּר אֶת רַב שָׁקֵ֨ה מִ/לָּכִ֧ישׁ יְרוּשָׁלְַ֛מָ/ה אֶל הַ/מֶּ֥לֶךְ חִזְקִיָּ֖הוּ בְּ/חֵ֣יל כָּבֵ֑ד וַֽ/יַּעֲמֹ֗ד בִּ/תְעָלַת֙ הַ/בְּרֵכָ֣ה הָ/עֶלְיוֹנָ֔ה בִּ/מְסִלַּ֖ת שְׂדֵ֥ה כוֹבֵֽס", "en": {"kjv": "And the king of Assyria sent Rabshakeh from Lachish to Jerusalem unto king Hezekiah with a great army. And he stood by the conduit of the upper pool in the highway of the fuller’s field.", "web": "The king of Assyria sent Rabshakeh from Lachish to Jerusalem to king Hezekiah with a large army. He stood by the aqueduct from the upper pool in the fuller’s field highway.", "bsb": "And the king of Assyria sent the Rabshakeh, with a great army, from Lachish to King Hezekiah at Jerusalem. And he stopped by the aqueduct of the upper pool, on the road to the Launderer’s Field.", "asv": "And the king of Assyria sent Rabshakeh from Lachish to Jerusalem unto king Hezekiah with a great army. And he stood by the conduit of the upper pool in the highway of the fuller’s field.", "ylt": "And the king of Asshur sendeth Rabshakeh from Lachish to Jerusalem, unto the king Hezekiah, with a heavy force, and he standeth by the conduit of the upper pool, in the highway of the fuller's field,", "dra": "And the king of the Assyrians sent Rabsaces from Lachis to Jerusalem, to king Ezechias with a great army, and he stood by the conduit of the upper pool in the way of the fuller's field.", "bbe": "And the king of Assyria sent the Rab-shakeh from Lachish to Jerusalem to King Hezekiah with a strong force, and he took up his position by the stream of the higher pool, by the highway of the washerman's", "geneva": "And the King of Asshur sent Rabshakeh from Lachish toward Ierusalem vnto King Hezekiah, with a great hoste, and he stood by ye conduite of the vpper poole in the path of the fullers fielde.", "wycliffe": "And the kyng of Assiriens sente Rapsases fro Lachis to Jerusalem, to kyng Ezechie, with greet power; and he stood at the watir cundit of the hiyere sisterne, in the weie of the feeld of a fullere.", "rotherham": "Then did the king of Assyria send Rabshakeh from Lachish to Jerusalem unto King Hezekiah with a heavy force,—and he took his stand by the upper channel of the pool, in the highway of the fuller’s field.", "darby": "And the king of Assyria sent Rab-shakeh from Lachish to Jerusalem, to king Hezekiah, with a strong force. And he stood by the aqueduct of the upper pool, on the highway of the fuller's field.", "twenty": "", "jps": "And the king of Assyria sent Rab-shakeh from Lachish to Jerusalem unto king Hezekiah with a great army. And he stood by the conduit of the upper pool in the highway of the fullers' field.", "acv": "And the king of Assyria sent Rabshakeh from Lachish to Jerusalem to king Hezekiah with a great army. And he stood by the conduit of the upper pool in the highway of the fuller's field.", "anderson": "", "haweis": "", "noyes": "And the king of Assyria sent Rabshakeh from Lachish to Jerusalem, with a great army, against King Hezekiah, and he halted at the aqueduct of the upper pool, in the highway to the fuller’s field.", "webster": "And the king of Assyria sent Rabshakeh from Lachish to Jerusalem against king Hezekiah with a great army. And he stood by the conduit of the upper pool in the highway of the fuller's field.", "vulgate": "et misit rex Assyriorum Rabsacen de Lachis in Hierusalem ad regem Ezechiam in manu gravi et stetit in aquaeductu piscinae superioris in via agri Fullonis;", "brenton": "And the king of the Assyrians sent Rabsaces out of Laches to Jerusalem to king Ezekias with a large force: and he stood by the conduit of the upper pool in the way of the fuller's field."}}, {"v": 3, "ref": "36:3", "o": "וַ/יֵּצֵ֥א אֵלָ֛י/ו אֶלְיָקִ֥ים בֶּן חִלְקִיָּ֖הוּ אֲשֶׁ֣ר עַל הַ/בָּ֑יִת וְ/שֶׁבְנָא֙ הַ/סֹּפֵ֔ר וְ/יוֹאָ֥ח בֶּן אָסָ֖ף הַ/מַּזְכִּֽיר", "en": {"kjv": "Then came forth unto him Eliakim, Hilkiah’s son, which was over the house, and Shebna the scribe, and Joah, Asaph’s son, the recorder.", "web": "Then Eliakim the son of Hilkiah, who was over the household, and Shebna the scribe, and Joah, the son of Asaph, the recorder came out to him.", "bsb": "Then Eliakim son of Hilkiah the palace administrator, Shebna the scribe, and Joah son of Asaph the recorder, went out to him.", "asv": "Then came forth unto him Eliakim the son of Hilkiah, who was over the household, and Shebna the scribe, and Joah, the son of Asaph, the recorder.", "ylt": "and go forth unto him doth Eliakim son of Hilkiah, who is over the house, and Shebna the scribe, and Joah son of Asaph, the remembrancer.", "dra": "And there went out to him Eliacim the son of Helcias, who was over the house, and Sobna the scribe, and Joahe the son of Asaph the recorder.", "bbe": "And there came out to him Eliakim, the son of Hilkiah, who was over the house, and Shebna the scribe, and Joah, the son of Asaph, the recorder.", "geneva": "Then came foorth vnto him Eliakim the sonne of Hilkiah the steward of the house, and Shebna the chanceler, and Ioah the sonne of Asaph the recorder.", "wycliffe": "And Eliachym, the sone of Elchie, that was on the hous, yede out to hym, and Sobna, the scryuen, and Joae, the sone of Asaph, the chaunceler.", "rotherham": "And there went out to him—Eliakim son of Hilkiah who was over the household,—and Shebna, the scribe, and Joah son of Asaph the recorder.", "darby": "Then came forth to him Eliakim the son of Hilkijah, who was over the household, and Shebna the scribe, and Joah the son of Asaph, the chronicler.", "twenty": "", "jps": "Then came forth unto him Eliakim the son of Hilkiah, that was over the household, and Shebna the scribe, and Joah the son of Asaph the recorder.", "acv": "Then Eliakim the son of Hilkiah came forth to him, who was over the household, and Shebna the scribe, and Joah, the son of Asaph, the recorder.", "anderson": "", "haweis": "", "noyes": "Then came forth to him Eliakim, the son of Hilkiah, who was over the palace, and Shebna the scribe, and Josh, the son of Asaph, the annalist.", "webster": "Then came forth to him Eliakim, Hilkiah's son, who was over the house, and Shebna the scribe, and Joah, Asaph's son, the recorder.", "vulgate": "et egressus est ad eum Eliachim filius Helciae qui erat super domum et Sobna scriba et Ioae filius Asaph a commentariis;", "brenton": "And there went forth to him Heliakim the steward, the son of Chelcias, and Somnas the scribe, and Joach the son of Asaph, the recorder."}}, {"v": 4, "ref": "36:4", "o": "וַ/יֹּ֤אמֶר אֲלֵי/הֶם֙ רַב שָׁקֵ֔ה אִמְרוּ נָ֖א אֶל חִזְקִיָּ֑הוּ כֹּֽה אָמַ֞ר הַ/מֶּ֤לֶךְ הַ/גָּדוֹל֙ מֶ֣לֶךְ אַשּׁ֔וּר מָ֧ה הַ/בִּטָּח֛וֹן הַ/זֶּ֖ה אֲשֶׁ֥ר בָּטָֽחְתָּ", "en": {"kjv": "And Rabshakeh said unto them, Say ye now to Hezekiah, Thus saith the great king, the king of Assyria, What confidence is this wherein thou trustest?", "web": "Rabshakeh said to them, “Now tell Hezekiah, ‘Thus says the great king, the king of Assyria, “What confidence is this in which you trust?", "bsb": "The Rabshakeh said to them, “Tell Hezekiah that this is what the great king, the king of Assyria, says: What is the basis of this confidence of yours?", "asv": "And Rabshakeh said unto them, Say ye now to Hezekiah, Thus saith the great king, the king of Assyria, What confidence is this wherein thou trustest?", "ylt": "And Rabshakeh saith unto them, `Say ye, I pray you, unto Hezekiah, `Thus said the great king, the king of Asshur, What is this confidence in which thou hast confided?", "dra": "And Rabsaces said to them: Tell Ezechias: Thus saith the great king, the king of the Assyrians: What is this confidence wherein thou trustest?", "bbe": "And the Rab-shakeh said to them, Say now to Hezekiah, These are the words of the great king, the king of Assyria: In what are you placing your hope?", "geneva": "And Rabshakeh sayde vnto them, Tell you Hezekiah, I pray you, Thus sayth the great King, the King of Asshur, What confidence is this, wherein thou trustest?", "wycliffe": "And Rapsases seide to hem, Seie ye to Ezechie, The greet king, the king of Assiriens, seith these thingis, What is the trist, in which thou tristist?", "rotherham": "And Rabshakeh said unto them, Pray you say unto Hezekiah,—Thus, saith the great king, the king of Assyria, What is this trust, wherewith thou dost trust?", "darby": "And Rab-shakeh said to them, Say now to Hezekiah, Thus says the great king, the king of Assyria: What confidence is this in which thou trustest?", "twenty": "", "jps": "And Rab-shakeh said unto them: 'Say ye now to Hezekiah: Thus saith the great king, the king of Assyria: What confidence is this wherein thou trustest?", "acv": "And Rabshakeh said to them, Say ye now to Hezekiah, Thus says the great king, the king of Assyria: What confidence is this in which thou trust?", "anderson": "", "haweis": "", "noyes": "And Rabshakeh said to them, Say ye to Hezekiah, Thus saith the great king, the king of Assyria: What a confidence is this which thou cherishest!", "webster": "And Rabshakeh said to them, Say ye now to Hezekiah, Thus saith the great king, the king of Assyria, What confidence [is] this in which thou trustest?", "vulgate": "et dixit ad eos Rabsaces dicite Ezechiae haec dicit rex magnus rex Assyriorum quae est ista fiducia qua confidis;", "brenton": "And Rabsaces said to them, Say to Ezekias, Thus says the great king, the king of the Assyrians, Why art thou secure?"}}, {"v": 5, "ref": "36:5", "o": "אָמַ֨רְתִּי֙ אַךְ דְּבַר שְׂפָתַ֔יִם עֵצָ֥ה וּ/גְבוּרָ֖ה לַ/מִּלְחָמָ֑ה עַתָּה֙ עַל מִ֣י בָטַ֔חְתָּ כִּ֥י מָרַ֖דְתָּ בִּֽ/י", "en": {"kjv": "I say, sayest thou, (but they are but vain words) I have counsel and strength for war: now on whom dost thou trust, that thou rebellest against me?", "web": "I say that your counsel and strength for the war are only vain words. Now in whom do you trust, that you have rebelled against me?", "bsb": "You claim to have a strategy and strength for war, but these are empty words. In whom are you now trusting, that you have rebelled against me?", "asv": "I say, thy counsel and strength for the war are but vain words: now on whom dost thou trust, that thou hast rebelled against me?", "ylt": "I have said: Only, a word of the lips! counsel and might are for battle: now, on whom hast thou trusted, that thou hast rebelled against me?", "dra": "Or with what counsel or strength dost thou prepare for war? on whom dost thou trust, that thou art revolted from me?", "bbe": "You say you have a design and strength for war, but these are only words: now to whom are you looking for support, that you have gone against my authority?", "geneva": "I say, Surely I haue eloquence, but counsell and strength are for the warre: on whom then doest thou trust, that thou rebellest against me?", "wycliffe": "ethir bi what councele ether strengthe disposist thou for to rebelle? on whom hast thou trist, for thou hast go awei fro me?", "rotherham": "I have said [sayest thou] —they are only words of the lips—Counsel and might have I for the war,—Now, upon whom dost thou trust, that thou hast rebelled against me?", "darby": "Thou sayest, but it is a word of the lips, [There is] counsel and strength for war. Now on whom dost thou rely, that thou hast revolted against me?", "twenty": "", "jps": "I said: It is but vain words; for counsel and strength are for the war. Now on whom dost thou trust, that thou hast rebelled against me?", "acv": "I say, thy counsel and strength for the war are but vain words. Now on whom do thou trust that thou have rebelled against me?", "anderson": "", "haweis": "", "noyes": "Thou sayest, (but it is vain talk,) \"I have counsel and strength for war.\" In whom, then, dost thou trust, that thou rebellest against me?", "webster": "I say, [sayest thou] (but [they are but] vain words) [I have] counsel and strength for war: now on whom dost thou trust, that thou rebellest against me?", "vulgate": "aut quo consilio vel fortitudine rebellare disponis super quem habes fiduciam quia recessisti a me;", "brenton": "Is war carried on with counsel and mere words of the lips? and now on whom dost thou trust, that thou rebellest against me?"}}, {"v": 6, "ref": "36:6", "o": "הִנֵּ֣ה בָטַ֡חְתָּ עַל מִשְׁעֶנֶת֩ הַ/קָּנֶ֨ה הָ/רָצ֤וּץ הַ/זֶּה֙ עַל מִצְרַ֔יִם אֲשֶׁ֨ר יִסָּמֵ֥ךְ אִישׁ֙ עָלָ֔י/ו וּ/בָ֥א בְ/כַפּ֖/וֹ וּ/נְקָבָ֑/הּ כֵּ֚ן פַּרְעֹ֣ה מֶֽלֶךְ מִצְרַ֔יִם לְ/כָֽל הַ/בֹּטְחִ֖ים עָלָֽי/ו", "en": {"kjv": "Lo, thou trustest in the staff of this broken reed, on Egypt; whereon if a man lean, it will go into his hand, and pierce it: so is Pharaoh king of Egypt to all that trust in him.", "web": "Behold, you trust in the staff of this bruised reed, even in Egypt, which if a man leans on it, it will go into his hand and pierce it. So is Pharaoh king of Egypt to all who trust in him.", "bsb": "Look now, you are trusting in Egypt, that splintered reed of a staff that will pierce the hand of anyone who leans on it. Such is Pharaoh king of Egypt to all who trust in him.", "asv": "Behold, thou trustest upon the staff of this bruised reed, even upon Egypt, whereon if a man lean, it will go into his hand, and pierce it: so is Pharaoh king of Egypt to all that trust on him.", "ylt": "`Lo, thou hast trusted on the staff of this broken reed--on Egypt--which a man leaneth on, and it hath gone into his hand, and pierced it--so is Pharaoh king of Egypt to all those trusting on him.", "dra": "Lo thou trustest upon this broken staff of a reed, upon Egypt: upon which if a man lean, it will go into his hand, and pierce it: so is Pharao king of Egypt to all that trust in him.", "bbe": "See, you are basing your hope on that broken rod of Egypt, which will go into a man's hand if he makes use of it for a support; for so is Pharaoh, king of Egypt, to all who put their faith in him.", "geneva": "Loe, thou trustest in this broken staffe of reede on Egypt, whereupon if a man leane, it will goe into his hand, and pearce it: so is Pharaoh King of Egypt, vnto all that trust in him.", "wycliffe": "Lo! thou tristist on this brokun staf of rehed, on Egipt, on which if a man restith, it schal entre in to his hoond, and schal perse it; so doith Farao, the kyng of Egipt, to alle men that tristen in hym.", "rotherham": "Lo! thou dost trust on the support of this bruised cane, on Egypt, whereon if a man lean it will enter his hand and lay it open,—So, is Pharaoh king of Egypt to all who trust upon him.", "darby": "Behold, thou reliest upon the staff of that broken reed, upon Egypt, on which if a man lean, it goes into his hand, and pierces it: so is Pharaoh king of Egypt to all that rely upon him.", "twenty": "", "jps": "Behold, thou trustest upon the staff of this bruised reed, even upon Egypt; whereon if a man lean, it will go into his hand, and pierce it; so is Pharaoh king of Egypt to all that trust on him.", "acv": "Behold, thou trust upon the staff of this bruised reed, even upon Egypt, on which if a man leans, it will go into his hand, and pierce it. So is Pharaoh king of Egypt to all who trust on him.", "anderson": "", "haweis": "", "noyes": "Behold, thou trustest in that broken reed-staff, Egypt, on which if a man lean, it will pierce his hand, and go through it. Such is Pharaoh, king of Egypt, to all that trust in him.", "webster": "Lo, thou trustest in the staff of this broken reed, on Egypt; on which if a man lean, it will enter his hand, and pierce it: so [is] Pharaoh king of Egypt to all that trust in him.", "vulgate": "ecce confidis super baculum harundineum confractum istum super Aegyptum cui si innisus fuerit homo intrabit in manu eius et perforabit eam sic Pharao rex Aegypti omnibus qui confidunt in eo;", "brenton": "Behold, thou trustest on this bruised staff of reed, on Egypt: as soon as a man leans upon it, it shall go into his hand, and pierce it: so is Pharao king of Egypt and all that trust in him."}}, {"v": 7, "ref": "36:7", "o": "וְ/כִי תֹאמַ֣ר אֵלַ֔/י אֶל יְהוָ֥ה אֱלֹהֵ֖י/נוּ בָּטָ֑חְנוּ הֲ/לוֹא ה֗וּא אֲשֶׁ֨ר הֵסִ֤יר חִזְקִיָּ֨הוּ֙ אֶת בָּמֹתָ֣י/ו וְ/אֶת מִזְבְּחֹתָ֔י/ו וַ/יֹּ֤אמֶר לִֽ/יהוּדָה֙ וְ/לִ/יר֣וּשָׁלִַ֔ם לִ/פְנֵ֛י הַ/מִּזְבֵּ֥חַ הַ/זֶּ֖ה תִּֽשְׁתַּחֲוֽוּ", "en": {"kjv": "But if thou say to me, We trust in the Lord our God: is it not he, whose high places and whose altars Hezekiah hath taken away, and said to Judah and to Jerusalem, Ye shall worship before this altar?", "web": "But if you tell me, ‘We trust in Yahweh our God,’ isn’t that he whose high places and whose altars Hezekiah has taken away, and has said to Judah and to Jerusalem, ‘You shall worship before this altar?’”", "bsb": "But if you say to me, ‘We trust in the LORD our God,’ is He not the One whose high places and altars Hezekiah has removed, saying to Judah and Jerusalem, ‘You must worship before this altar’?", "asv": "But if thou say unto me, We trust in Jehovah our God: is not that he, whose high places and whose altars Hezekiah hath taken away, and hath said to Judah and to Jerusalem, Ye shall worship before this altar?", "ylt": "`And dost thou say unto me, Unto Jehovah our God we have trusted? is it not He, whose high places and whose altars Hezekiah hath turned aside, and saith to Judah and to Jerusalem, Before this altar ye do bow yourselves?", "dra": "But if thou wilt answer me: We trust in the Lord our God: is it not he whose high places and altars Ezechias hath taken away, and hath said to Juda and Jerusalem: You shall worship before this altar?", "bbe": "And if you say to me, Our hope is in the Lord our God; is it not he whose high places and altars Hezekiah has taken away, saying to Judah and Jerusalem that worship may only be given before this altar?", "geneva": "But if thou say to me, We trust in the Lord our God. Is not that he, whose hie places and whose altars Hezekiah tooke downe, and said to Iudah and to Ierusalem, Ye shall worship before this altar?", "wycliffe": "That if thou answerist to me, We tristen in oure Lord God; whether it is not he, whose hiye places and auteris Esechie dide awei, and he seide to Juda and to Jerusalem, Ye schulen worschipe bifore this auter?", "rotherham": "But, if thou shouldst say unto me, In Yahweh our God, do we trust, Then is that not he whose high places and whose altars, Hezekiah hath removed, and said unto Judah and unto Jerusalem, Before this altar, shall ye bow yourselves down?", "darby": "And if thou say to me, We rely upon Jehovah ourGod: is it not he, whose high places and whose altars Hezekiah has removed, saying to Judah and Jerusalem, Ye shall worship before this altar?", "twenty": "", "jps": "But if thou say unto me: We trust in HaShem our G-d; is not that He, whose high places and whose altars Hezekiah hath taken away, and hath said to Judah and to Jerusalem: Ye shall worship before this altar?", "acv": "But if thou say to me, We trust in Jehovah our God. Is that not he whose high places and whose altars Hezekiah has taken away, and has said to Judah and to Jerusalem, Ye shall worship before this altar?", "anderson": "", "haweis": "", "noyes": "But if ye say to me, \"We trust in Jehovah, our God,\"—is it not he whose high places and whose altars Hezekiah hath taken away, and commanded Judah and Jerusalem to worship before this altar?", "webster": "But if thou shalt say to me, We trust in the LORD our God: [is it] not he, whose high places and whose altars Hezekiah hath taken away, and said to Judah and to Jerusalem, Ye shall worship before this altar?", "vulgate": "quod si responderis mihi in Domino Deo nostro confidimus nonne ipse est cuius abstulit Ezechias excelsa et altaria et dixit Iudae et Hierusalem coram altari isto adorabitis;", "brenton": "But if ye say, We trust in the Lord our God;"}}, {"v": 8, "ref": "36:8", "o": "וְ/עַתָּה֙ הִתְעָ֣רֶב נָ֔א אֶת אֲדֹנִ֖/י הַ/מֶּ֣לֶךְ אַשּׁ֑וּר וְ/אֶתְּנָ֤ה לְ/ךָ֙ אַלְפַּ֣יִם סוּסִ֔ים אִם תּוּכַ֕ל לָ֥/תֶת לְ/ךָ֖ רֹכְבִ֥ים עֲלֵי/הֶֽם", "en": {"kjv": "Now therefore give pledges, I pray thee, to my master the king of Assyria, and I will give thee two thousand horses, if thou be able on thy part to set riders upon them.", "web": "Now therefore, please make a pledge to my master the king of Assyria, and I will give you two thousand horses, if you are able on your part to set riders on them.", "bsb": "Now, therefore, make a bargain with my master, the king of Assyria. I will give you two thousand horses—if you can put riders on them!", "asv": "Now therefore, I pray thee, give pledges to my master the king of Assyria, and I will give thee two thousand horses, if thou be able on thy part to set riders upon them.", "ylt": "`And now, negotiate, I pray thee, with my lord the king of Asshur, and I give to thee two thousand horses, if thou art able to put for thee riders on them.", "dra": "And now deliver thyself up to my lord the king of the Assyrians, and I will give thee two thousand horses, and thou wilt not be able on thy part to find riders for them.", "bbe": "And now, take a chance with my master, the king of Assyria, and I will give you two thousand horses, if you are able to put horsemen on them.", "geneva": "Nowe therefore giue hostages to my lorde the King of Asshur, and I wil giue thee two thousand horses, if thou be able on thy part to set riders vpon them.", "wycliffe": "And now bitake thee to my lord, the kyng of Assiriens, and Y schal yyue to thee twei thousynde of horsis, and thou maist not yyue of thee stieris of tho horsis.", "rotherham": "Now, therefore, pledge thyself I pray thee with my lord, the king of Assyria,—That I supply thee with two thousand horses, If thou on thy part be able to set riders upon them;", "darby": "And now engage, I pray thee, with my master the king of Assyria, and I will give thee two thousand horses, if thou be able on thy part to set riders upon them.", "twenty": "", "jps": "Now therefore, I pray thee, make a wager with my master, the king of Assyria, and I will give thee two thousand horses, if thou be able on thy part to set riders upon them.", "acv": "Now therefore, I pray thee, give pledges to my master the king of Assyria, and I will give thee two thousand horses, if thou be able on thy part to set riders upon them.", "anderson": "", "haweis": "", "noyes": "Engage, now, with my master, the king of Assyria! and I will give thee two thousand horses, when thou art able to provide for thyself riders for them.", "webster": "Now therefore give pledges, I pray thee, to my master the king of Assyria, and I will give thee two thousand horses, if thou canst on thy part set riders upon them.", "vulgate": "et nunc trade te domino meo regi Assyriorum et dabo tibi duo milia equorum nec poteris ex te praebere ascensores eorum;", "brenton": "yet now make an agreement with my lord the king of the Assyrians, and I will give you two thousand horses, if ye shall be able to set riders upon them."}}, {"v": 9, "ref": "36:9", "o": "וְ/אֵ֣יךְ תָּשִׁ֗יב אֵ֠ת פְּנֵ֨י פַחַ֥ת אַחַ֛ד עַבְדֵ֥י אֲדֹנִ֖/י הַ/קְטַנִּ֑ים וַ/תִּבְטַ֤ח לְ/ךָ֙ עַל מִצְרַ֔יִם לְ/רֶ֖כֶב וּ/לְ/פָרָשִֽׁים", "en": {"kjv": "How then wilt thou turn away the face of one captain of the least of my master’s servants, and put thy trust on Egypt for chariots and for horsemen?", "web": "How then can you turn away the face of one captain of the least of my master’s servants, and put your trust on Egypt for chariots and for horsemen?", "bsb": "For how can you repel a single officer among the least of my master’s servants when you depend on Egypt for chariots and horsemen?", "asv": "How then canst thou turn away the face of one captain of the least of my master’s servants, and put thy trust on Egypt for chariots and for horsemen?", "ylt": "And how dost thou turn back the face of one captain of the least of the servants of my lord, and dost trust for thee on Egypt, for chariot and for horsemen?", "dra": "And how wilt thou stand against the face of the judge of one place, of the least of my master's servants? But if thou trust in Egypt, in chariots and in horsemen:", "bbe": "How then may you put to shame the least of my master's servants? and you have put your hope in Egypt for war-carriages and horsemen:", "geneva": "For howe canst thou despise any captaine of the least of my lordes seruants? and put thy trust on Egypt for charets and for horsemen?", "wycliffe": "And hou schalt thou abide the face of the iuge of o place of the lesse seruauntis of my lord? That if thou tristist in Egipt, and in cartis, and in knyytis;", "rotherham": "How then wilt thou turn away the face of one pasha of the least of my lord’s servants? Or hast thou on thy part trusted upon Egypt, for chariots and for horsemen?", "darby": "How then wilt thou turn away the face of one captain of the least of my master's servants? And thou reliest upon Egypt for chariots and for horsemen!", "twenty": "", "jps": "How then canst thou turn away the face of one captain, even of the least of my master's servants? yet thou puttest thy trust on Egypt for chariots and for horsemen!", "acv": "How then can thou turn away the face of one captain of the least of my master's servants, and put thy trust on Egypt for chariots and for horsemen?", "anderson": "", "haweis": "", "noyes": "How, then, canst thou resist a single captain, one of the least of the servants of my master? Yet thou trustest in Egypt, on account of her chariots and her horsemen.", "webster": "How then wilt thou turn away the face of one captain of the least of my master's servants, and put thy trust on Egypt for chariots and for horsemen?", "vulgate": "et quomodo sustinebis faciem iudicis unius loci ex servis domini mei minoribus quod si confidis in Aegypto in quadriga et in equitibus;", "brenton": "And how can ye then turn to the face of the satraps? They that trust on the Egyptians for horse and rider, are our servants."}}, {"v": 10, "ref": "36:10", "o": "וְ/עַתָּה֙ הֲ/מִ/בַּלְעֲדֵ֣י יְהוָ֔ה עָלִ֛יתִי עַל הָ/אָ֥רֶץ הַ/זֹּ֖את לְ/הַשְׁחִיתָ֑/הּ יְהוָה֙ אָמַ֣ר אֵלַ֔/י עֲלֵ֛ה אֶל הָ/אָ֥רֶץ הַ/זֹּ֖את וְ/הַשְׁחִיתָֽ/הּ", "en": {"kjv": "And am I now come up without the Lord against this land to destroy it? the Lord said unto me, Go up against this land, and destroy it.", "web": "Have I come up now without Yahweh against this land to destroy it? Yahweh said to me, “Go up against this land, and destroy it.”’”", "bsb": "So now, was it apart from the LORD that I have come up against this land to destroy it? The LORD Himself said to me, ‘Go up against this land and destroy it.’”", "asv": "And am I now come up without Jehovah against this land to destroy it? Jehovah said unto me, Go up against this land, and destroy it.", "ylt": "And now, without Jehovah have I come up against this land to destroy it? Jehovah said unto me, Go up unto this land, and thou hast destroyed it.'", "dra": "And am I now come up without the Lord against this land to destroy it? The Lord said to me: Go up against this land, and destroy it.", "bbe": "And have I now come to send destruction on this land without the Lord's authority? It was the Lord himself who said to me, Go up against this land and make it waste.", "geneva": "And am I now come vp without the Lord to this land to destroy it? The Lord sayd vnto me, Goe vp against this land and destroy it.", "wycliffe": "and now whethir Y stiede to this lond with out the Lord, that Y schulde distrie it? The Lord seide to me, Stie thou on this lond, and distrie thou it.", "rotherham": "But, now, is it, without Yahweh, that I have come up against this land to destroy it? Yahweh himself, said unto me, Go thou up against this land and destroy it!", "darby": "And now am I come up without Jehovah against this land to destroy it? Jehovah said to me, Go up against this land and destroy it.", "twenty": "", "jps": "And am I now come up without HaShem against this land to destroy it? HaShem said unto me: Go up against this land, and destroy it.'", "acv": "And have I now come up without Jehovah against this land to destroy it? Jehovah said to me, Go up against this land, and destroy it.", "anderson": "", "haweis": "", "noyes": "And am I now come up without Jehovah against this land to destroy it? Jehovah hath said to me, \"Go up against this land and destroy it!\"", "webster": "And am I now come up without the LORD against this land to destroy it? the LORD said to me, Go up against this land, and destroy it.", "vulgate": "et nunc numquid sine Domino ascendi ad terram istam ut disperderem eam Dominus dixit ad me ascende super terram istam et disperde eam;", "brenton": "And now, Have we come up against this land to fight against it without the Lord? The Lord said to me, Go up against this land, and destroy it."}}, {"v": 11, "ref": "36:11", "o": "וַ/יֹּ֣אמֶר אֶלְיָקִים֩ וְ/שֶׁבְנָ֨א וְ/יוֹאָ֜ח אֶל רַב שָׁקֵ֗ה דַּבֶּר נָ֤א אֶל עֲבָדֶ֨י/ךָ֙ אֲרָמִ֔ית כִּ֥י שֹׁמְעִ֖ים אֲנָ֑חְנוּ וְ/אַל תְּדַבֵּ֤ר אֵלֵ֨י/נוּ֙ יְהוּדִ֔ית בְּ/אָזְנֵ֣י הָ/עָ֔ם אֲשֶׁ֖ר עַל הַ/חוֹמָֽה", "en": {"kjv": "Then said Eliakim and Shebna and Joah unto Rabshakeh, Speak, I pray thee, unto thy servants in the Syrian language; for we understand it: and speak not to us in the Jews’ language, in the ears of the people that are on the wall.", "web": "Then Eliakim, Shebna and Joah said to Rabshakeh, “Please speak to your servants in Aramaic, for we understand it; and don’t speak to us in the Jews’ language in the hearing of the people who are on the wall.”", "bsb": "Then Eliakim, Shebna, and Joah said to the Rabshakeh, “Please speak to your servants in Aramaic, since we understand it. Do not speak to us in Hebrew in the hearing of the people on the wall.”", "asv": "Then said Eliakim and Shebna and Joah unto Rabshakeh, Speak, I pray thee, unto thy servants in the Syrian language; for we understand it: and speak not to us in the Jews’ language, in the ears of the people that are on the wall.", "ylt": "And Eliakim saith--and Shebna and Joah--unto Rabshakeh, `Speak, we pray thee, unto thy servants in Aramaean, for we are understanding; and do not speak unto us in Jewish, in the ears of the people who are on the wall.'", "dra": "And Eliacim, and Sobna, and Joahe said to Rabsaces: Speak to thy servants in the Syrian tongue: for we understand it: speak not to us in the Jews' language in the hearing of the people, that are upon the wall.", "bbe": "Then Eliakim and Shebna and Joah said to the Rab-shakeh, Please make use of the Aramaean language in talking to your servants, for we are used to it, and do not make use of the Jews' language in the hearing of the people on the wall.", "geneva": "Then sayd Eliakim and Shebna and Ioah vnto Rabshakeh, Speake, I pray thee, to thy seruants in the Aramites language, (for we vnderstand it) and talke not with vs in the Iewes tongue, in the audience of the people that are on the wall.", "wycliffe": "And Eliachym, and Sobna, and Joae, seiden to Rapsaces, Speke thou to thi seruauntis bi the langage of Sirie, for we vndurstonden; speke thou not to vs bi the langage of Jewis in the eeris of the puple, which is on the wal.", "rotherham": "Then said Eliakim, and Shebna, and Joah, unto Rabshakeh—Speak we pray thee unto thy servants in the Syrian language, for we, can, understand, it,—and do not speak unto us in the Jews’ language, in the ears of the people who are upon the wall.", "darby": "And Eliakim and Shebna and Joah said to Rab-shakeh, Speak, we pray thee, to thy servants in Syriac, for we understand it; and speak not to us in the Jewish [language] in the ears of the people that are upon the wall.", "twenty": "", "jps": "Then said Eliakim and Shebna and Joah unto Rab-shakeh: 'Speak, I pray thee, unto thy servants in the Aramean language, for we understand it; and speak not to us in the Jews' language, in the ears of the people that are on the wall.'", "acv": "Then Eliakim and Shebna and Joah said to Rabshakeh, Speak, I pray thee, to thy servants in the Syrian language, for we understand it. And speak not to us in the Jews' language, in the ears of the people who are on the wall.", "anderson": "", "haweis": "", "noyes": "Then said Eliakim and Shebna and Josh to Rabshakeh: Speak, we beseech thee, to thy servants in the Aramaic language, for we understand it; and speak not to us in the Jewish language, in the hearing of the people that are upon the wall.", "webster": "Then said Eliakim and Shebna and Joah to Rabshakeh, Speak, I pray thee, to thy servants in the Syrian language; for we understand [it]: and speak not to us in the Jew's language, in the ears of the people that [are] on the wall.", "vulgate": "et dixit Eliachim et Sobna et Ioae ad Rabsacen loquere ad servos tuos syra lingua intellegimus enim ne loquaris ad nos iudaice in auribus populi qui est super murum;", "brenton": "Then Eliakim and Somnas and Joach said to him, Speak to thy servants in the Syrian tongue; for we understand it: and speak not to us in the Jewish tongue: and wherefore speakest thou in the ears of the men on the wall?"}}, {"v": 12, "ref": "36:12", "o": "וַ/יֹּ֣אמֶר רַב שָׁקֵ֗ה הַ/אֶ֨ל אֲדֹנֶ֤י/ךָ וְ/אֵלֶ֨י/ךָ֙ שְׁלָחַ֣/נִי אֲדֹנִ֔/י לְ/דַבֵּ֖ר אֶת הַ/דְּבָרִ֣ים הָ/אֵ֑לֶּה הֲ/לֹ֣א עַל הָ/אֲנָשִׁ֗ים הַ/יֹּֽשְׁבִים֙ עַל הַ֣/חוֹמָ֔ה לֶ/אֱכֹ֣ל אֶת חראי/הם צוֹאָתָ֗/ם וְ/לִ/שְׁתּ֛וֹת אֶת שיני/הם מֵימֵ֥י רַגְלֵי/הֶ֖ם עִמָּ/כֶֽם", "en": {"kjv": "But Rabshakeh said, Hath my master sent me to thy master and to thee to speak these words? hath he not sent me to the men that sit upon the wall, that they may eat their own dung, and drink their own piss with you?", "web": "But Rabshakeh said, “Has my master sent me only to your master and to you, to speak these words, and not to the men who sit on the wall, who will eat their own dung and drink their own urine with you?”", "bsb": "But the Rabshakeh replied, “Has my master sent me to speak these words only to you and your master, and not to the men sitting on the wall, who are destined with you to eat their own dung and drink their own urine?”", "asv": "But Rabshakeh said, Hath my master sent me to thy master, and to thee, to speak these words? hath he not sent me to the men that sit upon the wall, to eat their own dung, and to drink their own water with you?", "ylt": "And Rabshakeh saith, `Unto thy lord, and unto thee, hath my lord sent me to speak these words? is it not for the men--those sitting on the wall to eat their own dung and to drink their own water with you?'", "dra": "And Rabsaces said to them: Hath my master sent me to thy master and to thee, to speak all these words; and not rather to the men that sit on the wall; that they may eat their own dung, and drink their urine with you?", "bbe": "But the Rab-shakeh said, Is it to your master or to you that my master has sent me to say these words? has he not sent me to the men seated on the wall? for they are the people who will be short of food with you when the town is shut in.", "geneva": "Then said Rabshakeh, Hath my master sent me to thy master, and to thee to speake these wordes, and not to the men that sit on the wall? that they may eate their owne doung, and drinke their owne pisse with you?", "wycliffe": "And Rapsaces seide to hem, Whether mi lord sente me to thi lord, and to thee, that Y schulde speke alle these wordis, and not rathere to the men that sitten on the wal, that thei ete her toordis, and drynke the pisse of her feet with you?", "rotherham": "But Rabshakeh said—Is it unto thy lord and unto thee, that my lord hath sent me, to speak these things? Is it not concerning the men who are tarrying upon the wall, that they may eat and drink what cometh from them, with you?", "darby": "And Rab-shakeh said, Is it to thy master and to thee that my master sent me to speak these words? Is it not to the men that sit on the wall, that they may eat their own dung, and drink their own urine with you?", "twenty": "", "jps": "But Rab-shakeh said: 'Hath my master sent me to thy master, and to thee, to speak these words? hath he not sent me to the men that sit upon the wall, to eat their own dung, and to drink their own water with you?'", "acv": "But Rabshakeh said, Has my master sent me to thy master, and to thee, to speak these words, and not to the men who sit upon the wall, to eat their own dung, and to drink their own urine with you?", "anderson": "", "haweis": "", "noyes": "But Rabshakeh said, Hath my master sent me to speak these words to thy master and to thee only, and not to the people who sit upon the wall, to eat their own dung, and to drink their own urine with you?", "webster": "But Rabshakeh said, Hath my master sent me to thy master and to thee to speak these words? [hath he] not [sent me] to the men that sit upon the wall, that they may devour their vilest excretions with you?", "vulgate": "et dixit ad eos Rabsaces numquid ad dominum tuum et ad te misit me dominus meus ut loquerer omnia verba ista et non potius ad viros qui sedent in muro ut comedant stercora sua et bibant urinam pedum suorum vobiscum;", "brenton": "And Rabsaces said to them, Has my lord sent me to your lord or to you, to speak these words? has he not sent me to the men that sit on the wall, that they may eat dung, and drink their water together with you?"}}, {"v": 13, "ref": "36:13", "o": "וַֽ/יַּעֲמֹד֙ רַב שָׁקֵ֔ה וַ/יִּקְרָ֥א בְ/קוֹל גָּד֖וֹל יְהוּדִ֑ית וַ/יֹּ֕אמֶר שִׁמְע֗וּ אֶת דִּבְרֵ֛י הַ/מֶּ֥לֶךְ הַ/גָּד֖וֹל מֶ֥לֶךְ אַשּֽׁוּר", "en": {"kjv": "Then Rabshakeh stood, and cried with a loud voice in the Jews’ language, and said, Hear ye the words of the great king, the king of Assyria.", "web": "Then Rabshakeh stood, and called out with a loud voice in the Jews’ language, and said, “Hear the words of the great king, the king of Assyria!", "bsb": "Then the Rabshakeh stood and called out loudly in Hebrew: “Hear the words of the great king, the king of Assyria!", "asv": "Then Rabshakeh stood, and cried with a loud voice in the Jews’ language, and said, Hear ye the words of the great king, the king of Assyria.", "ylt": "And Rabshakeh standeth and calleth with a great voice in Jewish, and saith, `Hear ye the words of the great king, the king of Asshur:", "dra": "Then Rabsaces stood, and cried out with a loud voice in the Jews' language, and said: Hear the words of the great king, the king of the Assyrians.", "bbe": "Then the Rab-shakeh got up and said with a loud voice in the Jews' language, Give ear to the words of the great king, the king of Assyria:", "geneva": "So Rabshakeh stood, and cryed with a loude voyce in the Iewes language, and sayd, Heare the wordes of the great King, of the King of Asshur.", "wycliffe": "And Rapsaces stood, and criede with greet vois in the langage of Jewis, and seide, Here ye the wordis of the greet kyng, the kyng of Assiriens.", "rotherham": "So then Rabshakeh took his stand, and cried out with a loud voice, in the Jews’ language, and said, Hear ye the words of the great king, the king of Assyria:", "darby": "And Rab-shakeh stood and cried with a loud voice in the Jewish [language], and said, Hear the words of the great king, the king of Assyria!", "twenty": "", "jps": "Then Rab-shakeh stood, and cried with a loud voice in the Jews' language, and said: 'Hear ye the words of the great king, the king of Assyria.", "acv": "Then Rabshakeh stood, and cried with a loud voice in the Jews' language, and said, Hear ye the words of the great king, the king of Assyria.", "anderson": "", "haweis": "", "noyes": "Then Rabshakeh stood and cried with a loud voice in the Jewish language, and said, Hear ye the words of the great king, the king of Assyria.", "webster": "Then Rabshakeh stood, and cried with a loud voice in the Jew's language, and said, Hear ye the words of the great king, the king of Assyria.", "vulgate": "et stetit Rabsaces et clamavit voce magna iudaice et dixit audite verba regis magni regis Assyriorum;", "brenton": "And Rabsaces stood and cried with a loud voice in the Jewish language, and said, Hear ye the words of the great king, the king of the Assyrians:"}}, {"v": 14, "ref": "36:14", "o": "כֹּ֚ה אָמַ֣ר הַ/מֶּ֔לֶךְ אַל יַשִּׁ֥א לָ/כֶ֖ם חִזְקִיָּ֑הוּ כִּ֥י לֹֽא יוּכַ֖ל לְ/הַצִּ֥יל אֶתְ/כֶֽם", "en": {"kjv": "Thus saith the king, Let not Hezekiah deceive you: for he shall not be able to deliver you.", "web": "Thus says the king, ‘Don’t let Hezekiah deceive you; for he will not be able to deliver you.", "bsb": "This is what the king says: Do not let Hezekiah deceive you, for he cannot deliver you.", "asv": "Thus saith the king, Let not Hezekiah deceive you; for he will not be able to deliver you:", "ylt": "Thus said the king, Let not Hezekiah lift you up, for he is not able to deliver you;", "dra": "Thus saith the king: Let not Ezechias deceive you, for he shall not be able to deliver you.", "bbe": "This is what the king says: Do not be tricked by Hezekiah, for there is no salvation for you in him.", "geneva": "Thus saith the King, Let not Hezekiah deceiue you: for he shall not be able to deliuer you.", "wycliffe": "The kyng seith these thingis, Esechie disseyue not you, for he may not delyuere you;", "rotherham": "Thus, saith the king, Let not Hezekiah deceive you,—for he shall not be able to deliver you.", "darby": "Thus says the king: Let not Hezekiah deceive you; for he will not be able to deliver you.", "twenty": "", "jps": "Thus saith the king: Let not Hezekiah beguile you, for he will not be able to deliver you;", "acv": "Thus says the king, Let not Hezekiah deceive you, for he will not be able to deliver you.", "anderson": "", "haweis": "", "noyes": "Thus saith the king: Let not Hezekiah deceive you, for he will not be able to deliver you.", "webster": "Thus saith the king, Let not Hezekiah deceive you: for he will not be able to deliver you.", "vulgate": "haec dicit rex non seducat vos Ezechias quia non poterit eruere vos;", "brenton": "thus says the king, Let not Ezekias deceive you with words: he will not be able to deliver you."}}, {"v": 15, "ref": "36:15", "o": "וְ/אַל יַבְטַ֨ח אֶתְ/כֶ֤ם חִזְקִיָּ֨הוּ֙ אֶל יְהוָ֣ה לֵ/אמֹ֔ר הַצֵּ֥ל יַצִּילֵ֖/נוּ יְהוָ֑ה לֹ֤א תִנָּתֵן֙ הָ/עִ֣יר הַ/זֹּ֔את בְּ/יַ֖ד מֶ֥לֶךְ אַשּֽׁוּר", "en": {"kjv": "Neither let Hezekiah make you trust in the Lord, saying, The Lord will surely deliver us: this city shall not be delivered into the hand of the king of Assyria.", "web": "Don’t let Hezekiah make you trust in Yahweh, saying, “Yahweh will surely deliver us. This city won’t be given into the hand of the king of Assyria.”’", "bsb": "Do not let Hezekiah persuade you to trust in the LORD when he says, ‘The LORD will surely deliver us; this city will not be given into the hand of the king of Assyria.’", "asv": "neither let Hezekiah make you trust in Jehovah, saying, Jehovah will surely deliver us; this city shall not be given into the hand of the king of Assyria.", "ylt": "and let not Hezekiah make you trust unto Jehovah, saying, Jehovah doth certainly deliver us, this city is not given into the hand of the king of Asshur.", "dra": "And let not Ezechias make you trust in the Lord, saying: The Lord will surely deliver us, and this city shall not be given into the hands of the king of the Assyrians.", "bbe": "And do not let Hezekiah make you put your faith in the Lord, saying, The Lord will certainly keep us safe, and this town will not be given into the hands of the king of Assyria.", "geneva": "Neither let Hezekiah make you to trust in the Lord, saying, The Lord will surely deliuer vs: this citie shall not be giuen ouer into the hand of the King of Asshur.", "wycliffe": "and Ezechie yyue not to you trist on the Lord, and seie, The Lord delyuerynge schal delyuere vs; this citee schal not be youun in to the hoond of the kyng of Assiriens.", "rotherham": "Neither let Hezekiah cause you to trust in Yahweh saying, Yahweh, will certainly deliver, us,—this city shall not be given over, into the hand of the king of Assyria.", "darby": "Neither let Hezekiah make you rely upon Jehovah, saying, Jehovah will certainly deliver us; this city shall not be given into the hand of the king of Assyria.", "twenty": "", "jps": "neither let Hezekiah make you trust in HaShem, saying: HaShem will surely deliver us; this city shall not be given into the hand of the king of Assyria.", "acv": "Neither let Hezekiah make you trust in Jehovah, saying, Jehovah will surely deliver us. This city shall not be given into the hand of the king of Assyria.", "anderson": "", "haweis": "", "noyes": "And let not Hezekiah persuade you to trust in Jehovah, saying, \"Jehovah will certainly deliver us. This city shall not be delivered into the hands of the king of Assyria.\"", "webster": "Neither let Hezekiah make you trust in the LORD, saying, the LORD will surely deliver us: this city shall not be delivered into the hand of the king of Assyria.", "vulgate": "et non vobis tribuat fiduciam Ezechias super Domino dicens eruens liberabit nos Dominus non dabitur civitas ista in manu regis Assyriorum;", "brenton": "And let not Ezekias say to you, That God will deliver you, and this city will not at all be delivered into the hand of the king of the Assyrians."}}, {"v": 16, "ref": "36:16", "o": "אַֽל תִּשְׁמְע֖וּ אֶל חִזְקִיָּ֑הוּ כִּי֩ כֹ֨ה אָמַ֜ר הַ/מֶּ֣לֶךְ אַשּׁ֗וּר עֲשֽׂוּ אִתִּ֤/י בְרָכָה֙ וּ/צְא֣וּ אֵלַ֔/י וְ/אִכְל֤וּ אִישׁ גַּפְנ/וֹ֙ וְ/אִ֣ישׁ תְּאֵנָת֔/וֹ וּ/שְׁת֖וּ אִ֥ישׁ מֵי בוֹרֽ/וֹ", "en": {"kjv": "Hearken not to Hezekiah: for thus saith the king of Assyria, Make an agreement with me by a present, and come out to me: and eat ye every one of his vine, and every one of his fig tree, and drink ye every one the waters of his own cistern;", "web": "Don’t listen to Hezekiah, for thus says the king of Assyria, ‘Make your peace with me, and come out to me; and each of you eat from his vine, and each one from his fig tree, and each one of you drink the waters of his own cistern;", "bsb": "Do not listen to Hezekiah, for this is what the king of Assyria says: Make peace with me and come out to me. Then every one of you will eat from his own vine and his own fig tree, and drink water from his own cistern,", "asv": "Hearken not to Hezekiah: for thus saith the king of Assyria, Make your peace with me, and come out to me; and eat ye every one of his vine, and every one of his fig-tree, and drink ye every one the waters of his own cistern;", "ylt": "`Do not hearken unto Hezekiah, for thus said the king of Asshur, Make ye with me a blessing, and come out unto me, and eat ye each of his vine, and each of his fig-tree, and drink ye each the waters of his own well,", "dra": "Do not hearken to Ezechias: for thus said the king of the Assyrians: Do with me that which is for your advantage, and come out to me, and eat ye every one of his vine, and every one of his fig tree, and drink ye every one the water of his cistern,", "bbe": "Do not give ear to Hezekiah, for this is what the king of Assyria says, Make peace with me, and come out to me; and everyone will be free to take the fruit of his vine and of his fig-tree, and the water of his spring;", "geneva": "Hearken not to Hezekiah: for thus sayth the King of Asshur, Make appointment with me, and come out to me, that euery man may eate of his owne vine, and euery man of his owne fig tree, and drinke euery man the water of his owne well,", "wycliffe": "Nyle ye here Ezechie. For whi the kyng of Assiriens seith these thingis, Make ye blessyng with me, and go ye out to me; and ete ye ech man his vyner, and ech man his fige tre, and drynke ye ech man the water of his cisterne,", "rotherham": "Do not hearken unto Hezekiah,—for, thus, saith the king of Assyria, Deal with me thankfully, and come out unto me, Then shall ye eat, Every one of his own vine and Every one of his own fig-tree, And drink every one the Waters of his own cistern:", "darby": "Hearken not to Hezekiah; for thus says the king of Assyria: Make peace with me and come out to me; and eat every one of his vine, and every one of his fig-tree, and drink every one the waters of his own cistern;", "twenty": "", "jps": "Hearken not to Hezekiah; for thus saith the king of Assyria: Make your peace with me, and come out to me; and eat ye every one of his vine, and every one of his fig-tree, and drink ye every one the waters of his own cistern;", "acv": "Hearken not to Hezekiah. For thus says the king of Assyria, Make your peace with me, and come out to me, and eat ye everyone of his vine, and everyone of his fig tree, and drink ye everyone the waters of his own cistern,", "anderson": "", "haweis": "", "noyes": "Hearken not to Hezekiah; for thus saith the king of Assyria: Make peace with me, and come out to me; and ye shall every one eat of his own vine, and every one of his own fig-tree, and ye shall every one drink the waters of his own cistern,", "webster": "Hearken not to Hezekiah: for thus saith the king of Assyria, Make [an agreement] with me [by] a present, and come out to me: and eat ye every one of his vine, and every one of his fig-tree, and drink ye every one the waters of his own cistern;", "vulgate": "nolite audire Ezechiam haec enim dicit rex Assyriorum facite mecum benedictionem et egredimini ad me et comedite unusquisque vineam suam et unusquisque ficum suam et bibite unusquisque aquam cisternae suae;", "brenton": "Hearken not to Ezekias: thus says the king of the Assyrians, If ye wish to be blessed, come out to me: and ye shall eat every one of his vine and his fig-trees, and ye shall drink water out of your own cisterns:"}}, {"v": 17, "ref": "36:17", "o": "עַד בֹּאִ֕/י וְ/לָקַחְתִּ֥י אֶתְ/כֶ֖ם אֶל אֶ֣רֶץ כְּ/אַרְצְ/כֶ֑ם אֶ֤רֶץ דָּגָן֙ וְ/תִיר֔וֹשׁ אֶ֥רֶץ לֶ֖חֶם וּ/כְרָמִֽים", "en": {"kjv": "Until I come and take you away to a land like your own land, a land of corn and wine, a land of bread and vineyards.", "web": "until I come and take you away to a land like your own land, a land of grain and new wine, a land of bread and vineyards.", "bsb": "until I come and take you away to a land like your own—a land of grain and new wine, a land of bread and vineyards.", "asv": "until I come and take you away to a land like your own land, a land of grain and new wine, a land of bread and vineyards.", "ylt": "till my coming in, and I have taken you unto a land like your own land, a land of corn and wine, a land of bread and vineyards;", "dra": "Till I come and take you away to a land, like to your own, a land of corn and of wine, a land of bread and vineyards.", "bbe": "Till I come and take you away to a land like yours, a land of grain and wine, a land of bread and vine-gardens.", "geneva": "Till I come and bring you to a land like your owne land, euen a land of wheate, and wine, a land of bread and vineyardes,", "wycliffe": "til Y come, and take awei you to a lond which is as youre lond; to a lond of whete and of wyn, to a lond of looues and of vyneris.", "rotherham": "Until I come and take you, into A land like your own land,—A land of corn and new wine, A land of bread and vineyards:—", "darby": "until I come and take you away to a land like your own land, a land of corn and wine, a land of bread and vineyards.", "twenty": "", "jps": "until I come and take you away to a land like your own land, a land of corn and wine, a land of bread and vineyards.", "acv": "until I come and take you away to a land like your own land, a land of grain and new wine, a land of bread and vineyards.", "anderson": "", "haweis": "", "noyes": "until I come, and take you to a land like your own land; a land of corn, and of new wine, a land of bread and of vineyards.", "webster": "Until I come and take you away to a land like your own land, a land of corn and wine, a land of bread and vineyards.", "vulgate": "donec veniam et tollam vos ad terram quae est ut terra vestra terram frumenti et vini terram panum et vinearum;", "brenton": "until I come and take you to a land, like your own land, a land of corn and wine, and bread, and vineyards."}}, {"v": 18, "ref": "36:18", "o": "פֶּן יַסִּ֨ית אֶתְ/כֶ֤ם חִזְקִיָּ֨הוּ֙ לֵ/אמֹ֔ר יְהוָ֖ה יַצִּילֵ֑/נוּ הַ/הִצִּ֜ילוּ אֱלֹהֵ֤י הַ/גּוֹיִם֙ אִ֣ישׁ אֶת אַרְצ֔/וֹ מִ/יַּ֖ד מֶ֥לֶךְ אַשּֽׁוּר", "en": {"kjv": "Beware lest Hezekiah persuade you, saying, The Lord will deliver us. Hath any of the gods of the nations delivered his land out of the hand of the king of Assyria?", "web": "Beware lest Hezekiah persuade you, saying, “Yahweh will deliver us.” Have any of the gods of the nations delivered their lands from the hand of the king of Assyria?", "bsb": "Do not let Hezekiah mislead you when he says, ‘The LORD will deliver us.’ Has the god of any nation ever delivered his land from the hand of the king of Assyria?", "asv": "Beware lest Hezekiah persuade you, saying, Jehovah will deliver us. Hath any of the gods of the nations delivered his land out of the hand of the king of Assyria?", "ylt": "lest Hezekiah doth persuade you, saying, Jehovah doth deliver us. `Have the gods of the nations delivered each his land out of the hand of the king of Asshur?", "dra": "Neither let Ezechias trouble you, saying: The Lord will deliver us. Have any of the gods of the nations delivered their land out of the hand of the king of the Assyrians?", "bbe": "Give no attention to Hezekiah when he says to you, The Lord will keep us safe. Has any one of the gods of the nations kept his land from falling into the hands of the king of Assyria?", "geneva": "Least Hezekiah deceiue you, saying, The Lord wil deliuer vs. Hath any of the gods of the nations deliuered his land out of the hand of the King of Asshur?", "wycliffe": "Ezechie disturble not you, and seie, The Lord schal delyuere vs. Whether the goddis of folkis delyuereden ech his lond fro the hond of the kyng of Assiriens?", "rotherham": "Lest Hezekiah, persuade you, saying, Yahweh will deliver us! Have the gods of the nations, delivered,—any one of them—his country, out of the hand of the king of Assyria?", "darby": "Let not Hezekiah persuade you, saying, Jehovah will deliver us. Has any of thegods of the nations delivered his land out of the hand of the king of Assyria?", "twenty": "", "jps": "Beware lest Hezekiah persuade you, saying: HaShem will deliver us. Hath any of the gods of the nations delivered his land out of the hand of the king of Assyria?", "acv": "Beware lest Hezekiah persuade you, saying, Jehovah will deliver us. Has any of the gods of the nations delivered his land out of the hand of the king of Assyria?", "anderson": "", "haweis": "", "noyes": "Be not persuaded by Hezekiah, when he saith, \"Jehovah will deliver us.\" Have the gods of the nations delivered every one his own land from the hand of the king of Assyria? Where are the gods of Hamath and of Arphad?", "webster": "[Beware] lest Hezekiah persuade you, saying, The LORD will deliver us. Hath any of the gods of the nations delivered his land out of the hand of the king of Assyria?", "vulgate": "ne conturbet vos Ezechias dicens Dominus liberabit nos numquid liberaverunt dii gentium unusquisque terram suam de manu regis Assyriorum;", "brenton": "Let not Ezekias deceive you, saying, God will deliver you. Have the gods of the nations delivered each one his own land out of the hand of the king of the Assyrians?"}}, {"v": 19, "ref": "36:19", "o": "אַיֵּ֞ה אֱלֹהֵ֤י חֲמָת֙ וְ/אַרְפָּ֔ד אַיֵּ֖ה אֱלֹהֵ֣י סְפַרְוָ֑יִם וְ/כִֽי הִצִּ֥ילוּ אֶת שֹׁמְר֖וֹן מִ/יָּדִֽ/י", "en": {"kjv": "Where are the gods of Hamath and Arphad? where are the gods of Sepharvaim? and have they delivered Samaria out of my hand?", "web": "Where are the gods of Hamath and Arpad? Where are the gods of Sepharvaim? Have they delivered Samaria from my hand?", "bsb": "Where are the gods of Hamath and Arpad? Where are the gods of Sepharvaim? Have they delivered Samaria from my hand?", "asv": "Where are the gods of Hamath and Arpad? where are the gods of Sepharvaim? and have they delivered Samaria out of my hand?", "ylt": "Where are the gods of Hamath and Arpad? Where the gods of Sepharvaim, that they have delivered Samaria out of my hand?", "dra": "Where is the god of Emath and of Arphad? where is the god of Sepharvaim? have they delivered Samaria out of my hand?", "bbe": "Where are the gods of Hamath and of Arpad? where are the gods of Sepharvaim? where are the gods of Samaria? and have they kept Samaria out of my hand?", "geneva": "Where is the god of Hamath, and of Arpad? where is the god of Sepharuaim? or howe haue they deliuered Samaria out of mine hand?", "wycliffe": "Where is the god of Emath, and of Arphat? Where is the god of Sepharuaym? Whethir thei delyueriden Samarie fro myn hond?", "rotherham": "Where are the gods of Hamath and Arpad? Where are the gods of Sepharvaim? If indeed they had only delivered Samaria, out of my hand!", "darby": "Where are thegods of Hamath and of Arpad? where are thegods of Sepharvaim? and have they delivered Samaria out of my hand?", "twenty": "", "jps": "Where are the gods of Hamath and Arpad? where are the gods of Sepharvaim? and have they delivered Samaria out of my hand?", "acv": "Where are the gods of Hamath and Arpad? Where are the gods of Sepharvaim? And have they delivered Samaria out of my hand?", "anderson": "", "haweis": "", "noyes": "Where are the gods of Sepharvaim? And did the gods deliver Samaria from my hand?", "webster": "Where [are] the gods of Hamath and Arpad? where [are] the gods of Sepharvaim? and have they delivered Samaria out of my hand?", "vulgate": "ubi est deus Emath et Arfad ubi est deus Seffarvaim numquid liberaverunt Samariam de manu mea;", "brenton": "Where is the god of Emath, and Arphath? and where is the god of Eppharuaim? have they been able to deliver Samaria out of my hand?"}}, {"v": 20, "ref": "36:20", "o": "מִ֗י בְּ/כָל אֱלֹהֵ֤י הָֽ/אֲרָצוֹת֙ הָ/אֵ֔לֶּה אֲשֶׁר הִצִּ֥ילוּ אֶת אַרְצָ֖/ם מִ/יָּדִ֑/י כִּֽי יַצִּ֧יל יְהוָ֛ה אֶת יְרוּשָׁלִַ֖ם מִ/יָּדִֽ/י", "en": {"kjv": "Who are they among all the gods of these lands, that have delivered their land out of my hand, that the Lord should deliver Jerusalem out of my hand?", "web": "Who are they among all the gods of these countries that have delivered their country out of my hand, that Yahweh should deliver Jerusalem out of my hand?’”", "bsb": "Who among all the gods of these lands has delivered his land from my hand? How then can the LORD deliver Jerusalem from my hand?”", "asv": "Who are they among all the gods of these countries, that have delivered their country out of my hand, that Jehovah should deliver Jerusalem out of my hand?", "ylt": "Who among all the gods of these lands are they who have delivered their land out of my hand, that Jehovah doth deliver Jerusalem out of my hand?'", "dra": "Who is there among all the gods of these lands, that hath delivered his country out of my hand, that the Lord may deliver Jerusalem out of my hand?", "bbe": "Who among all the gods of these countries have kept their country from falling into my hand, to give cause for the thought that the Lord will keep Jerusalem from falling into my hand?", "geneva": "Who is hee among all the gods of these lands, that hath deliuered their countrey out of mine hand, that the Lord should deliuer Ierusalem out of mine hand?", "wycliffe": "Who is of alle goddis of these londis, that delyueride his lond fro myn hond, that the Lord delyuere Jerusalem fro myn hond?", "rotherham": "Who are they, among all the gods of these countries that have delivered their country out of my hand? That, Yahweh, should deliver, Jerusalem, out of my hand!", "darby": "Who are they among all thegods of these countries that have delivered their country out of my hand, that Jehovah should deliver Jerusalem out of my hand?", "twenty": "", "jps": "Who are they among all the gods of these countries, that have delivered their country out of my hand, that HaShem should deliver Jerusalem out of my hand?'", "acv": "Who are they among all the gods of these countries that have delivered their country out of my hand, that Jehovah should deliver Jerusalem out of my hand?", "anderson": "", "haweis": "", "noyes": "Who is there among all the gods of these lands, that hath delivered his land out of my hand, that Jehovah should deliver Jerusalem out of my hand?", "webster": "Who [are they] among all the gods of these lands, that have delivered their land out of my hand, that the LORD should deliver Jerusalem out of my hand?", "vulgate": "quis est ex omnibus diis terrarum istarum qui eruerit terram suam de manu mea ut eruat Dominus Hierusalem de manu mea;", "brenton": "Which is the god of all these nations, that has delivered his land out of my hand, that God should deliver Jerusalem out of my hand?"}}, {"v": 21, "ref": "36:21", "o": "וַֽ/יַּחֲרִ֔ישׁוּ וְ/לֹֽא עָנ֥וּ אֹת֖/וֹ דָּבָ֑ר כִּֽי מִצְוַ֨ת הַ/מֶּ֥לֶךְ הִ֛יא לֵ/אמֹ֖ר לֹ֥א תַעֲנֻֽ/הוּ", "en": {"kjv": "But they held their peace, and answered him not a word: for the king’s commandment was, saying, Answer him not.", "web": "But they remained silent, and said nothing in reply, for the king’s commandment was, “Don’t answer him.”", "bsb": "But the people remained silent and did not answer a word, for Hezekiah had commanded, “Do not answer him.”", "asv": "But they held their peace, and answered him not a word; for the king’s commandment was, saying, Answer him not.", "ylt": "And they keep silent, and have not answered him a word, for a command of the king is, saying, `Do not answer him.'", "dra": "And they held their peace, and answered him not a word. For the king had commanded, saying: Answer him not.", "bbe": "But they kept quiet and gave him no answer: for the king's order was, Give him no answer.", "geneva": "Then they kept silence, and answered him not a worde: for the Kings commandement was, saying, Answere him not.", "wycliffe": "And thei weren stille, and answeriden not to hym a word. For whi the kyng comaundide to hem, and seide, Answere ye not to him.", "rotherham": "But they held their peace, and answered him not a word,—for the command of the king, it was, saying,—Ye must not answer him.", "darby": "And they were silent, and answered him not a word; for the king's command was, saying, Answer him not.", "twenty": "", "jps": "But they held their peace, and answered him not a word; for the king's commandment was, saying: 'Answer him not.'", "acv": "But they held their peace, and answered him not a word. For the king's commandment was, saying, Answer him not.", "anderson": "", "haweis": "", "noyes": "But the people held their peace, and answered him not a word; for the king’s command was, \"Answer him not.\"", "webster": "But they held their peace, and answered him not a word: for the king's commandment was, saying, Answer him not.", "vulgate": "et siluerunt et non responderunt ei verbum mandaverat enim rex dicens ne respondeatis ei;", "brenton": "And they were silent, and none answered him a word; because the king had commanded that none should answer."}}, {"v": 22, "ref": "36:22", "o": "וַ/יָּבֹ֣א אֶלְיָקִ֣ים בֶּן חִלְקִיָּ֣הוּ אֲשֶׁר עַל הַ֠/בַּיִת וְ/שֶׁבְנָ֨א הַ/סּוֹפֵ֜ר וְ/יוֹאָ֨ח בֶּן אָסָ֧ף הַ/מַּזְכִּ֛יר אֶל חִזְקִיָּ֖הוּ קְרוּעֵ֣י בְגָדִ֑ים וַ/יַּגִּ֣ידוּ ל֔/וֹ אֵ֖ת דִּבְרֵ֥י רַב שָׁקֵֽה", "en": {"kjv": "Then came Eliakim, the son of Hilkiah, that was over the household, and Shebna the scribe, and Joah, the son of Asaph, the recorder, to Hezekiah with their clothes rent, and told him the words of Rabshakeh.", "web": "Then Eliakim the son of Hilkiah, who was over the household, and Shebna the scribe, and Joah, the son of Asaph, the recorder, came to Hezekiah with their clothes torn, and told him the words of Rabshakeh.", "bsb": "Then Hilkiah’s son Eliakim the palace administrator, Shebna the scribe, and Asaph’s son Joah the recorder came to Hezekiah with their clothes torn, and they relayed to him the words of the Rabshakeh.", "asv": "Then came Eliakim the son of Hilkiah, that was over the household, and Shebna the scribe, and Joah, the son of Asaph, the recorder, to Hezekiah with their clothes rent, and told him the words of Rabshakeh.", "ylt": "And Eliakim son of Hilkiah, who is over the house, cometh in, and Shebna the scribe, and Joah son of Asaph, the remembrancer, unto Hezekiah with rent garments, and they declare to him the words of Rabshakeh.", "dra": "And Eliacim the son of Helcias, that was over the house, and Sobna the scribe, and Joahe the son of Asaph the recorder, went in to Ezechias with their garments rent, and told him the words of Rabsaces.", "bbe": "Then Eliakim, the son of Hilkiah, who was over the house, and Shebna the scribe, and Joah, the son of Asaph, the recorder, came to Hezekiah with their clothing parted as a sign of grief, and gave him an account of what the Rab-shakeh had said.", "geneva": "Then came Eliakim the sonne of Hilkiah the steward of the house, and Shebna the chanceller, and Ioah the sonne of Asaph the recorder, vnto Hezekiah with rent clothes, and tolde him the wordes of Rabshakeh.", "wycliffe": "And Eliachym, the sone of Elchie, that was on the hous, and Sobna, the scryueyn, and Joae, the sone of Asaph, chaunceler, entriden with to-rent clothis to Ezechie, and telde to hym the wordis of Rapsaces.", "rotherham": "Then came in—Eliakim son of Hilkiah who was over the household, and Shebna the scribe, and Joah son of Asaph, the recorder, unto Hezekiah, with rent clothes,—and they told him the words of Rabshakeh.", "darby": "And Eliakim the son of Hilkijah, who was over the household, and Shebna the scribe, and Joah the son of Asaph, the chronicler, came to Hezekiah, with their garments rent, and told him the words of Rab-shakeh.", "twenty": "", "jps": "Then came Eliakim the son of Hilkiah, that was over the household, and Shebna the scribe, and Joah the son of Asaph the recorder, to Hezekiah with their clothes rent, and told him the words of Rab-shakeh.", "acv": "Then Eliakim the son of Hilkiah came, who was over the household, and Shebna the scribe, and Joah, the son of Asaph, the recorder, to Hezekiah with their clothes torn, and told him the words of Rabshakeh.", "anderson": "", "haweis": "", "noyes": "Then came Eliakim, the son of Hilkiah, that was over the palace, and Shebna the scribe, and Joah, the son of Asaph, the annalist, to Hezekiah, with their clothes rent, and told him the words of Rabshakeh.", "webster": "Then came Eliakim the son of Hilkiah, that [was] over the household, and Shebna the scribe, and Joah, the son of Asaph, the recorder, to Hezekiah with [their] clothes rent, and told him the words of Rabshakeh.", "vulgate": "et ingressus est Eliachim filius Helciae qui erat super domum et Sobna scriba et Ioae filius Asaph a commentariis ad Ezechiam scissis vestibus et nuntiaverunt ei verba Rabsacis;", "brenton": "And Heliakim the son of Chelcias, the steward, and Somnas the military scribe, and Joach the son of Asaph, the recorder, came in to Ezekias, having their garments rent, and they reported to him the words of Rabsaces."}}]}, {"c": 37, "verses": [{"v": 1, "ref": "37:1", "o": "וַ/יְהִ֗י כִּ/שְׁמֹ֨עַ֙ הַ/מֶּ֣לֶךְ חִזְקִיָּ֔הוּ וַ/יִּקְרַ֖ע אֶת בְּגָדָ֑י/ו וַ/יִּתְכַּ֣ס בַּ/שָּׂ֔ק וַ/יָּבֹ֖א בֵּ֥ית יְהוָֽה", "en": {"kjv": "And it came to pass, when king Hezekiah heard it, that he rent his clothes, and covered himself with sackcloth, and went into the house of the Lord.", "web": "When king Hezekiah heard it, he tore his clothes, covered himself with sackcloth, and went into Yahweh’s house.", "bsb": "On hearing this report, King Hezekiah tore his clothes, put on sackcloth, and entered the house of the LORD.", "asv": "And it came to pass, when king Hezekiah heard it, that he rent his clothes, and covered himself with sackcloth, and went into the house of Jehovah.", "ylt": "And it cometh to pass, at the king Hezekiah's hearing, that he rendeth his garments, and covereth himself with sackcloth, and entereth the house of Jehovah,", "dra": "And it came to pass, when king Ezechias had heard it, that he rent his garments and covered himself with sackcloth, and went into the house of the Lord.", "bbe": "And on hearing it Hezekiah took off his robe and put on haircloth and went into the house of the Lord.", "geneva": "And when the King Hezekiah heard it, he rent his clothes, and put on sackcloth and came into the House of the Lord.", "wycliffe": "And it was don, whanne kyng Ezechie hadde herd, he to-rente hise clothis, and he was wlappid in a sak, and entride in to the hous of the Lord.", "rotherham": "And it came to pass, when King Hezekiah heard it, that he rent his clothes,—and covered himself with sackcloth, and entered the house of Yahweh;", "darby": "And it came to pass when king Hezekiah heard [it], that he rent his garments, and covered himself with sackcloth, and went into the house of Jehovah.", "twenty": "", "jps": "And it came to pass, when king Hezekiah heard it, that he rent his clothes, and covered himself with sackcloth, and went into the house of HaShem.", "acv": "And it came to pass, when king Hezekiah heard it, that he tore his clothes, and covered himself with sackcloth, and went into the house of Jehovah.", "anderson": "", "haweis": "", "noyes": "And when the king, Hezekiah, heard it, he rent his clothes, and covered himself with sackcloth, and went into the house of Jehovah.", "webster": "And it came to pass, when king Hezekiah heard [it], that he rent his clothes, and covered himself with sackcloth, and went into the house of the LORD.", "vulgate": "et factum est cum audisset rex Ezechias scidit vestimenta sua et obvolutus est sacco et intravit in domum Domini;", "brenton": "And it came to pass, when king Ezekias heard it, that he rent his clothes, and put on sackcloth, and went up to the house of the Lord."}}, {"v": 2, "ref": "37:2", "o": "וַ֠/יִּשְׁלַח אֶת אֶלְיָקִ֨ים אֲשֶׁר עַל הַ/בַּ֜יִת וְ/אֵ֣ת שֶׁבְנָ֣א הַ/סּוֹפֵ֗ר וְ/אֵת֙ זִקְנֵ֣י הַ/כֹּהֲנִ֔ים מִתְכַּסִּ֖ים בַּ/שַּׂקִּ֑ים אֶל יְשַֽׁעְיָ֥הוּ בֶן אָמ֖וֹץ הַ/נָּבִֽיא", "en": {"kjv": "And he sent Eliakim, who was over the household, and Shebna the scribe, and the elders of the priests covered with sackcloth, unto Isaiah the prophet the son of Amoz.", "web": "He sent Eliakim, who was over the household, and Shebna the scribe, and the elders of the priests, covered with sackcloth, to Isaiah the prophet, the son of Amoz.", "bsb": "And he sent Eliakim the palace administrator, Shebna the scribe, and the leading priests, all wearing sackcloth, to the prophet Isaiah son of Amoz", "asv": "And he sent Eliakim, who was over the household, and Shebna the scribe, and the elders of the priests, covered with sackcloth, unto Isaiah the prophet the son of Amoz.", "ylt": "and sendeth Eliakim, who is over the house, and Shebna the scribe, and the elders of the priests, covering themselves with sackcloth, unto Isaiah son of Amoz the prophet,", "dra": "And he sent Eliacim who was over the house, and Sobna the scribe, and the ancients of the priests covered with sackcloth, to Isaiah the son of Amos the prophet.", "bbe": "And he sent Eliakim, who was over the house, and Shebna the scribe, and the chief priests, dressed in haircloth, to Isaiah the prophet, the son of Amoz.", "geneva": "And he sent Eliakim the stewarde of the house, aud Shebna the chanceller, with the Elders of the Priestes, clothed in sackcloth vnto Isaiah the Prophet, the sonne of Amoz.", "wycliffe": "And he sente Eliachym, that was on the hous, and Sobna, the scryuen, and the eldre men of prestis, hilid with sackis, to Isaie, the prophete, the sone of Amos.", "rotherham": "and sent Eliakim who was over the household and Shebna the scribe and the elders of the priests, covered with sackcloth,—unto Isaiah the prophet, Son of Amoz;", "darby": "And he sent Eliakim, who was over the household, and Shebna the scribe, and the elders of the priests, covered with sackcloth, to the prophet Isaiah the son of Amoz.", "twenty": "", "jps": "And he sent Eliakim, who was over the household, and Shebna the scribe, and the elders of the priests, covered with sackcloth, unto Isaiah the prophet the son of Amoz.", "acv": "And he sent Eliakim, who was over the household, and Shebna the scribe, and the elders of the priests, covered with sackcloth, to Isaiah the prophet the son of Amoz.", "anderson": "", "haweis": "", "noyes": "And he sent Eliakim, who was over the palace, and Shebna the scribe, and the elders of the priests, covered with sackcloth, to Isaiah the prophet, the son of Amoz.", "webster": "And he sent Eliakim, who [was] over the household, and Shebna the scribe, and the elders of the priests covered with sackcloth, to Isaiah the prophet the son of Amoz.", "vulgate": "et misit Eliachim qui erat super domum et Sobnam scribam et seniores de sacerdotibus opertos saccis ad Isaiam filium Amos prophetam;", "brenton": "And he sent Heliakim the steward, and Somnas the scribe, and the elders of the priests clothed with sackcloth, to Esaias the son of Amos, the prophet. And they said to him, Thus says Ezekias,"}}, {"v": 3, "ref": "37:3", "o": "וַ/יֹּאמְר֣וּ אֵלָ֗י/ו כֹּ֚ה אָמַ֣ר חִזְקִיָּ֔הוּ יוֹם צָרָ֧ה וְ/תוֹכֵחָ֛ה וּ/נְאָצָ֖ה הַ/יּ֣וֹם הַ/זֶּ֑ה כִּ֣י בָ֤אוּ בָנִים֙ עַד מַשְׁבֵּ֔ר וְ/כֹ֥חַ אַ֖יִן לְ/לֵדָֽה", "en": {"kjv": "And they said unto him, Thus saith Hezekiah, This day is a day of trouble, and of rebuke, and of blasphemy: for the children are come to the birth, and there is not strength to bring forth.", "web": "They said to him, “Thus says Hezekiah, ‘This day is a day of trouble, and of rebuke, and of rejection; for the children have come to the birth, and there is no strength to give birth.", "bsb": "to tell him, “This is what Hezekiah says: Today is a day of distress, rebuke, and disgrace; for children have come to the point of birth, but there is no strength to deliver them.", "asv": "And they said unto him, Thus saith Hezekiah, This day is a day of trouble, and of rebuke, and of contumely; for the children are come to the birth, and there is not strength to bring forth.", "ylt": "and they say unto him, `Thus said Hezekiah, A day of distress, and rebuke, and despising, is this day; for come have sons unto the birth, and power there is not to bear.", "dra": "And they said to him: Thus saith Ezechias: This day is a day of tribulation, and of rebuke, and of blasphemy: for the children are come to the birth, and there is not strength to bring forth.", "bbe": "And they said to him, Hezekiah says, This day is a day of trouble and punishment and shame: for the children are ready to come to birth, but there is no strength to give birth to them.", "geneva": "And they sayd vnto him, Thus saith Hezekiah, This day is a day of tribulation and of rebuke and blasphemie: for the children are come to the birth, and there is no strength to bring foorth.", "wycliffe": "And thei seiden to hym, Ezechie seith these thingis, A dai of tribulacioun, and of angwisch, and of chastisyng, and of blasfemye is this dai; for children camen `til to childberyng, and vertu of childberyng is not.", "rotherham": "and they said unto him, Thus, saith Hezekiah, A day of distress and rebuke and reviling, is this day,—For children are come to the birth, and, strength, is there none to bring forth.", "darby": "And they said to him, Thus says Hezekiah: This day is a day of trouble, and of rebuke, and of reviling; for the children are come to the birth, and there is not strength to bring forth.", "twenty": "", "jps": "And they said unto him: 'Thus saith Hezekiah: This day is a day of trouble, and of rebuke, and of contumely; for the children are come to the birth, and there is not strength to bring forth.", "acv": "And they said to him, Thus says Hezekiah, This day is a day of trouble, and of rebuke, and of blasphemy, for the sons have come to the birth, and there is not strength to bring forth.", "anderson": "", "haweis": "", "noyes": "And they said to him, Thus saith Hezekiah: This day is a day of distress, of rebuke, and of contempt; for the children have come to the birth, and there is not strength to bring forth.", "webster": "And they said to him, Thus saith Hezekiah, This day [is] a day of trouble, and of rebuke, and of blasphemy: for the children are come to the birth, and [there is] not strength to bring forth.", "vulgate": "et dixerunt ad eum haec dicit Ezechias dies tribulationis et correptionis et blasphemiae dies haec quia venerunt filii usque ad partum et virtus non est parienti;", "brenton": "To-day is a day of affliction, and reproach, and rebuke, and anger: for the pangs are come upon the travailing woman, but she has not strength to bring forth."}}, {"v": 4, "ref": "37:4", "o": "אוּלַ֡י יִשְׁמַע֩ יְהוָ֨ה אֱלֹהֶ֜י/ךָ אֵ֣ת דִּבְרֵ֣י רַב שָׁקֵ֗ה אֲשֶׁר֩ שְׁלָח֨/וֹ מֶֽלֶךְ אַשּׁ֤וּר אֲדֹנָי/ו֙ לְ/חָרֵף֙ אֱלֹהִ֣ים חַ֔י וְ/הוֹכִ֨יחַ֙ בַּ/דְּבָרִ֔ים אֲשֶׁ֥ר שָׁמַ֖ע יְהוָ֣ה אֱלֹהֶ֑י/ךָ וְ/נָשָׂ֣אתָ תְפִלָּ֔ה בְּעַ֥ד הַ/שְּׁאֵרִ֖ית הַ/נִּמְצָאָֽה", "en": {"kjv": "It may be the Lord thy God will hear the words of Rabshakeh, whom the king of Assyria his master hath sent to reproach the living God, and will reprove the words which the Lord thy God hath heard: wherefore lift up thy prayer for the remnant that is left.", "web": "It may be Yahweh your God will hear the words of Rabshakeh, whom the king of Assyria his master has sent to defy the living God, and will rebuke the words which Yahweh your God has heard. Therefore lift up your prayer for the remnant that is left.’”", "bsb": "Perhaps the LORD your God will hear the words of the Rabshakeh, whom his master the king of Assyria has sent to defy the living God, and He will rebuke him for the words that the LORD your God has heard. Therefore lift up a prayer for the remnant that still survives.”", "asv": "It may be Jehovah thy God will hear the words of Rabshakeh, whom the king of Assyria his master hath sent to defy the living God, and will rebuke the words which Jehovah thy God hath heard: wherefore lift up thy prayer for the remnant that is left.", "ylt": "`It may be Jehovah thy God doth hear the words of Rabshakeh with which the king of Asshur his lord hath sent him to reproach the living God, and hath decided concerning the words that Jehovah thy God hath heard, and thou hast lifted up prayer for the remnant that is found.'", "dra": "It may be the Lord thy God will hear the words of Rabsaces, whom the king of the Assyrians his master hath sent to blaspheme the living God, and to reproach with words which the Lord thy God hath heard: wherefore lift up by prayer for the remnant that is left.", "bbe": "It may be that the Lord your God will give ear to the words of the Rab-shakeh, whom the king of Assyria, his master, has sent to say evil things against the living God, and will make his words come to nothing: so make your prayer for the rest of the people.", "geneva": "If so be the Lord thy God hath heard the wordes of Rabshakeh, whom the King of Asshur his master hath sent to raile on the liuing God, and to reproch him with wordes which the Lord thy God hath heard, then lift thou vp thy prayer for the remnant that are left.", "wycliffe": "Therfor reise thou preier for the relifs that ben foundun, if in ony maner thi Lord God here the wordis of Rapsaces, whom the king of Assiriens, his lord, sente, for to blasfeme lyuynge God, and to dispise bi the wordis, whiche thi Lord God herde.", "rotherham": "It may be, that Yahweh thy God will hear the words of Rabshakeh whom the king of Assyria his lord, hath sent to reproach a Living God, and will rebuke the words which Yahweh thy God hath heard,—Wherefore lift thou up a prayer, for the remnant that remaineth.", "darby": "It may be Jehovah thyGod will hear the words of Rab-shakeh, whom the king of Assyria his master has sent to reproach the livingGod, and will rebuke the words which Jehovah thyGod hath heard. Therefore lift up a prayer for the remnant that is left.", "twenty": "", "jps": "It may be HaShem thy G-d will hear the words of Rab-shakeh, whom the king of Assyria his master hath sent to taunt the living G-d, and will rebuke the words which HaShem thy G-d hath heard; wherefore make prayer for the remnant that is left.'", "acv": "It may be Jehovah thy God will hear the words of Rabshakeh, whom the king of Assyria his master has sent to defy the living God, and will rebuke the words which Jehovah thy God has heard. Therefore lift up thy prayer for the remnant that is left.", "anderson": "", "haweis": "", "noyes": "It may be that Jehovah, thy God, will hear the words of Rabshakeh, whom the king of Assyria, his master, hath sent to reproach the living God, and to revile him with the words which Jehovah, thy God, hath heard. Do thou, therefore, lift up thy prayer for the remnant of the people, that is yet left.", "webster": "It may be the LORD thy God will hear the words of Rabshakeh, whom the king of Assyria his master hath sent to reproach the living God, and will reprove the words which the LORD thy God hath heard: wherefore lift up [thy] prayer for the remnant that is left.", "vulgate": "si quo modo audiat Dominus Deus tuus verba Rabsaces quem misit rex Assyriorum dominus suus ad blasphemandum Deum viventem et obprobrandum sermonibus quos audivit Dominus Deus tuus leva ergo orationem pro reliquiis quae reppertae sunt;", "brenton": "May the Lord thy God hear the words of Rabsaces, which the king of the Assyrians has sent, to reproach the living God, even to reproach with the words which the Lord thy God has heard: therefore thou shalt pray to thy Lord for these that are left."}}, {"v": 5, "ref": "37:5", "o": "וַ/יָּבֹ֗אוּ עַבְדֵ֛י הַ/מֶּ֥לֶךְ חִזְקִיָּ֖הוּ אֶל יְשַׁעְיָֽהוּ", "en": {"kjv": "So the servants of king Hezekiah came to Isaiah.", "web": "So the servants of king Hezekiah came to Isaiah.", "bsb": "So the servants of King Hezekiah went to Isaiah,", "asv": "So the servants of king Hezekiah came to Isaiah.", "ylt": "And the servants of king Hezekiah come in unto Isaiah,", "dra": "And the servants of Ezechias came to Isaiah.", "bbe": "So the servants of King Hezekiah came to Isaiah.", "geneva": "So the seruants of the King Hezekiah came to Isaiah.", "wycliffe": "And the seruauntis of kyng Esechie camen to Isaie;", "rotherham": "So the servants of King Hezekiah came unto Isaiah.", "darby": "And the servants of king Hezekiah came to Isaiah.", "twenty": "", "jps": "So the servants of king Hezekiah came to Isaiah.", "acv": "So the servants of king Hezekiah came to Isaiah.", "anderson": "", "haweis": "", "noyes": "And the servants of King Hezekiah came to Isaiah.", "webster": "So the servants of king Hezekiah came to Isaiah.", "vulgate": "et venerunt servi regis Ezechiae ad Isaiam;", "brenton": "So the servants of king Ezekias came to Esaias."}}, {"v": 6, "ref": "37:6", "o": "וַ/יֹּ֤אמֶר אֲלֵי/הֶם֙ יְשַֽׁעְיָ֔הוּ כֹּ֥ה תֹאמְר֖וּ/ן אֶל אֲדֹנֵי/כֶ֑ם כֹּ֣ה אָמַ֣ר יְהוָ֗ה אַל תִּירָא֙ מִ/פְּנֵ֤י הַ/דְּבָרִים֙ אֲשֶׁ֣ר שָׁמַ֔עְתָּ אֲשֶׁ֧ר גִּדְּפ֛וּ נַעֲרֵ֥י מֶלֶךְ אַשּׁ֖וּר אוֹתִֽ/י", "en": {"kjv": "And Isaiah said unto them, Thus shall ye say unto your master, Thus saith the Lord, Be not afraid of the words that thou hast heard, wherewith the servants of the king of Assyria have blasphemed me.", "web": "Isaiah said to them, “Tell your master, ‘Thus says Yahweh, “Don’t be afraid of the words that you have heard, with which the servants of the king of Assyria have blasphemed me.", "bsb": "who replied, “Tell your master that this is what the LORD says: ‘Do not be afraid of the words you have heard, with which the servants of the king of Assyria have blasphemed Me.", "asv": "And Isaiah said unto them, Thus shall ye say to your master, Thus saith Jehovah, Be not afraid of the words that thou hast heard, wherewith the servants of the king of Assyria have blasphemed me.", "ylt": "and Isaiah saith unto them, `Thus do ye say unto your lord, Thus said Jehovah, Be not afraid because of the words that thou hast heard, with which the servants of the king of Asshur have reviled Me.", "dra": "And Isaiah said to them: Thus shall you say to your master: Thus saith the Lord: Be not afraid of the words that thou hast heard, with which the servants of the king of the Assyrians have blasphemed me.", "bbe": "And Isaiah said to them, This is what you are to say to your master: The Lord says, Be not troubled by the words which the servants of the king of Assyria have said against me in your hearing.", "geneva": "And Isaiah sayde vnto them, Thus say vnto your master, Thus saith the Lord, Be not afrayd of the wordes that thou hast heard, wherewith the seruants of the king of Asshur haue blasphemed me.", "wycliffe": "and Isaie seide to hem, Ye schulen seie these thingis to youre lord, The Lord seith these thingis, Drede thou not of the face of wordis whiche thou herdist, bi whiche the children of the kyng of Assiriens blasfemyden me.", "rotherham": "And Isaiah said unto them, Thus, shall ye, surely say, unto your lord,—Thus, saith Yahweh—Be not thou afraid because of the words which thou hast heard, wherewith the servants of the king of Assyria have reviled, Me.", "darby": "And Isaiah said to them, Thus shall ye say to your master, Thus saith Jehovah: Be not afraid of the words that thou hast heard, wherewith the servants of the king of Assyria have blasphemed me.", "twenty": "", "jps": "And Isaiah said unto them: 'Thus shall ye say to your master: Thus saith HaShem: Be not afraid of the words that thou hast heard, wherewith the servants of the king of Assyria have blasphemed Me.", "acv": "And Isaiah said to them, Thus shall ye say to your master, Thus says Jehovah: Be not afraid of the words that thou have heard, with which the servants of the king of Assyria have blasphemed me.", "anderson": "", "haweis": "", "noyes": "And Isaiah said to them, Thus shall ye say to your master: Thus saith Jehovah: Be not afraid on account of the words which thou hast heard, with which the servants of the king of Assyria have blasphemed me.", "webster": "And Isaiah said to them, Thus shall ye say to your master, Thus saith the LORD, Be not afraid of the words that thou hast heard, with which the servants of the king of Assyria have blasphemed me.", "vulgate": "et dixit ad eos Isaias haec dicetis domino vestro haec dicit Dominus ne timeas a facie verborum quae audisti quibus blasphemaverunt pueri regis Assyriorum me;", "brenton": "And Esaias said to them, Thus shall ye say to your master, Thus saith the Lord, Be not thou afraid at the words which thou hast heard, wherewith the ambassadors of the king of the Assyrians have reproached me,"}}, {"v": 7, "ref": "37:7", "o": "הִנְ/נִ֨י נוֹתֵ֥ן בּ/וֹ֙ ר֔וּחַ וְ/שָׁמַ֥ע שְׁמוּעָ֖ה וְ/שָׁ֣ב אֶל אַרְצ֑/וֹ וְ/הִפַּלְתִּ֥י/ו בַּ/חֶ֖רֶב בְּ/אַרְצֽ/וֹ", "en": {"kjv": "Behold, I will send a blast upon him, and he shall hear a rumour, and return to his own land; and I will cause him to fall by the sword in his own land.", "web": "Behold, I will put a spirit in him and he will hear news, and will return to his own land. I will cause him to fall by the sword in his own land.”’”", "bsb": "Behold, I will put a spirit in him so that he will hear a rumor and return to his own land, where I will cause him to fall by the sword.’”", "asv": "Behold, I will put a spirit in him, and he shall hear tidings, and shall return unto his own land; and I will cause him to fall by the sword in his own land.", "ylt": "Lo, I am giving in him a spirit, and he hath heard a report, and hath turned back unto his land, and I have caused him to fall by the sword in his land.'", "dra": "Behold, I will send a spirit upon him, and he shall hear a message, and shall return to his own country, and I will cause him to fall by the sword in his own country.", "bbe": "See, I will put a spirit into him, and bad news will come to his ears, and he will go back to his land; and there I will have him put to death.", "geneva": "Beholde, I wil send a blast vpon him, and he shall heare a noyse, and returne to his owne land, and I will cause him to fall by the sword in his owne land.", "wycliffe": "Lo! Y schal yyue to hym a spirit, and he schal here a messanger; and he schal turne ayen to his londe, and Y schal make hym to falle doun bi swerd in his lond.", "rotherham": "Behold me! about to let go against him a blast of alarm, and when he heareth the report, then will he return to his own country,—and I will cause him to fall by the sword in his own land.", "darby": "Behold, I will put a spirit into him, and he shall hear tidings, and shall return to his own land; and I will cause him to fall by the sword in his own land.", "twenty": "", "jps": "Behold, I will put a spirit in him, and he shall hear a rumour, and shall return unto his own land; and I will cause him to fall by the sword in his own land.'", "acv": "Behold, I will put a spirit in him, and he shall hear news, and shall return to his own land. And I will cause him to fall by the sword in his own land.", "anderson": "", "haweis": "", "noyes": "Behold, I will put a spirit within him, so that he shall hear a rumor, and return to his own land; and I will cause him to fall by the sword in his own land.", "webster": "Behold, I will send a blast upon him, and he shall hear a rumor, and return to his own land; and I will cause him to fall by the sword in his own land.", "vulgate": "ecce ego dabo ei spiritum et audiet nuntium et revertetur ad terram suam et corruere eum faciam gladio in terra sua;", "brenton": "Behold, I will send a blast upon him, and he shall hear a report, and return to his own country, and he shall fall by the sword in his own land."}}, {"v": 8, "ref": "37:8", "o": "וַ/יָּ֨שָׁב֙ רַב שָׁקֵ֔ה וַ/יִּמְצָא֙ אֶת מֶ֣לֶךְ אַשּׁ֔וּר נִלְחָ֖ם עַל לִבְנָ֑ה כִּ֣י שָׁמַ֔ע כִּ֥י נָסַ֖ע מִ/לָּכִֽישׁ", "en": {"kjv": "So Rabshakeh returned, and found the king of Assyria warring against Libnah: for he had heard that he was departed from Lachish.", "web": "So Rabshakeh returned, and found the king of Assyria warring against Libnah, for he had heard that he was departed from Lachish.", "bsb": "When the Rabshakeh heard that the king of Assyria had left Lachish, he withdrew and found the king fighting against Libnah.", "asv": "So Rabshakeh returned, and found the king of Assyria warring against Libnah; for he had heard that he was departed from Lachish.", "ylt": "And Rabshakeh turneth back and findeth the king of Asshur fighting against Libnah, for he hath heard that he hath journeyed from Lachish.", "dra": "And Rabsaces returned, and found the king of the Assyrians besieging Lobna. For he had heard that he was departed from Lachis.", "bbe": "So the Rab-shakeh went back, and when he got there the king of Assyria was making war against Libnah: for it had come to his ears that the king of Assyria had gone away from Lachish.", "geneva": "So Rabshakeh returned, and found the King of Asshur fighting against Libnah: for he had heard that he was departed from Lachish.", "wycliffe": "Forsothe Rapsaces turnede ayen, and foond the kyng of Assiriens fiytynge ayens Lobna; for he hadde herd, that the kyng was gon fro Lachis.", "rotherham": "So Rabshakeh returned, and found the king of Assyria, warring against Libnah,—for he had heard, that he had broken up from Lachish.", "darby": "And Rab-shakeh returned, and found the king of Assyria warring against Libnah; for he had heard that he had departed from Lachish.", "twenty": "", "jps": "So Rab-shakeh returned, and found the king of Assyria warring against Libnah; for he had heard that he was departed from Lachish.", "acv": "So Rabshakeh returned, and found the king of Assyria warring against Libnah, for he had heard that he was departed from Lachish.", "anderson": "", "haweis": "", "noyes": "Then Rabshakeh returned, and found the king of Assyria warring against Libnah, for he had heard that he had departed from Lachish.", "webster": "So Rabshakeh returned, and found the king of Assyria warring against Libnah: for he had heard that he had departed from Lachish.", "vulgate": "reversus est autem Rabsaces et invenit regem Assyriorum proeliantem adversus Lobna audierat enim quia profectus esset de Lachis;", "brenton": "So Rabsaces returned, and found the king of the Assyrians besieging Lobna: for he had heard that he had departed from Lachis."}}, {"v": 9, "ref": "37:9", "o": "וַ/יִּשְׁמַ֗ע עַל תִּרְהָ֤קָה מֶֽלֶךְ כּוּשׁ֙ לֵ/אמֹ֔ר יָצָ֖א לְ/הִלָּחֵ֣ם אִתָּ֑/ךְ וַ/יִּשְׁמַע֙ וַ/יִּשְׁלַ֣ח מַלְאָכִ֔ים אֶל חִזְקִיָּ֖הוּ לֵ/אמֹֽר", "en": {"kjv": "And he heard say concerning Tirhakah king of Ethiopia, He is come forth to make war with thee. And when he heard it, he sent messengers to Hezekiah, saying,", "web": "He heard news concerning Tirhakah king of Ethiopia, “He has come out to fight against you.” When he heard it, he sent messengers to Hezekiah, saying,", "bsb": "Now Sennacherib had been warned about Tirhakah king of Cush: “He has set out to fight against you.” On hearing this, Sennacherib sent messengers to Hezekiah, saying,", "asv": "And he heard say concerning Tirhakah king of Ethiopia, He is come out to fight against thee. And when he heard it, he sent messengers to Hezekiah, saying,", "ylt": "And he heareth concerning Tirhakah king of Cush, saying, `He hath come out to fight with thee;' and he heareth, and sendeth messengers unto Hezekiah, saying,", "dra": "And he heard say about Tharaca the king of Ethiopia: He is come forth to fight against thee. And when he heard it, he sent messengers to Ezechias, saying:", "bbe": "And when news came to him that Tirhakah, king of Ethiopia, had made an attack on him, ... And he sent representatives to Hezekiah, king of Judah, saying,", "geneva": "He heard also men say of Tirhakah, King of Ethiopia, Beholde, he is come out to fight against thee: and when he heard it, he sent other messengers to Hezekiah, saying,", "wycliffe": "And the kyng herde messangeris seiynge of Theracha, kyng of Ethiopiens, He is gon out to fiyte ayens thee. And whanne he hadde herd this thing, he sente messangeris to Ezechie, and seide, Ye schulen seie,", "rotherham": "And he heard it reported concerning Tirhakah king of Ethiopia, saying, He hath come forth to fight with thee,—so when he heard it, he sent messengers unto Hezekiah, saying:", "darby": "And he heard say of Tirhakah king of Ethiopia, He has come forth to make war with thee. And when he heard [it], he sent messengers to Hezekiah, saying,", "twenty": "", "jps": "And he heard say concerning Tirhakah king of Ethiopia: 'He is come out to fight against thee.' And when he heard it, he sent messengers to Hezekiah, saying:", "acv": "And he heard say concerning Tirhakah king of Ethiopia, He has come out to fight against thee. And when he heard it, he sent messengers to Hezekiah, saying,", "anderson": "", "haweis": "", "noyes": "Then he heard concerning Tirhakah, king of Ethiopia, that it was said, \"He is come forth to war against thee.\" And when he heard it, he sent messengers to Hezekiah and said,", "webster": "And he heard it said concerning Tirhakah king of Cush, He is come forth to make war with thee. And when he heard [it], he sent messengers to Hezekiah, saying,", "vulgate": "et audivit de Tharaca rege Aethiopiae dicentes egressus est ut pugnet contra te quod cum audisset misit nuntios ad Ezechiam dicens;", "brenton": "And Tharaca king of the Ethiopians went forth to attack him. And when he heard it, he turned aside, and sent messengers to Ezekias, saying,"}}, {"v": 10, "ref": "37:10", "o": "כֹּ֣ה תֹאמְר֗וּ/ן אֶל חִזְקִיָּ֤הוּ מֶֽלֶךְ יְהוּדָה֙ לֵ/אמֹ֔ר אַל יַשִּֽׁאֲ/ךָ֣ אֱלֹהֶ֔י/ךָ אֲשֶׁ֥ר אַתָּ֛ה בּוֹטֵ֥חַ בּ֖/וֹ לֵ/אמֹ֑ר לֹ֤א תִנָּתֵן֙ יְר֣וּשָׁלִַ֔ם בְּ/יַ֖ד מֶ֥לֶךְ אַשּֽׁוּר", "en": {"kjv": "Thus shall ye speak to Hezekiah king of Judah, saying, Let not thy God, in whom thou trustest, deceive thee, saying, Jerusalem shall not be given into the hand of the king of Assyria.", "web": "“Thus you shall speak to Hezekiah king of Judah, saying, ‘Don’t let your God in whom you trust deceive you, saying, “Jerusalem won’t be given into the hand of the king of Assyria.”", "bsb": "“Give this message to Hezekiah king of Judah: ‘Do not let your God, in whom you trust, deceive you by saying that Jerusalem will not be delivered into the hand of the king of Assyria.", "asv": "Thus shall ye speak to Hezekiah king of Judah, saying, Let not thy God in whom thou trustest deceive thee, saying, Jerusalem shall not be given into the hand of the king of Assyria.", "ylt": "`Thus do ye speak unto Hezekiah king of Judah, saying, Let not thy God lift thee up in whom thou art trusting, saying, Jerusalem is not given into the hand of the king of Asshur.", "dra": "Thus shall you speak to Ezechias the king of Juda, saying: Let not thy God deceive thee, in whom thou trustest, saying: Jerusalem shall not be given into the hands of the king of the Assyrians.", "bbe": "This is what you are to say to Hezekiah, king of Judah: Let not your God, in whom is your faith, give you a false hope, saying, Jerusalem will not be given into the hands of the king of Assyria.", "geneva": "Thus shall ye speake to Hezekiah King of Iudah, saying, Let not thy God deceiue thee, in whom thou trustest, saying, Ierusalem shall not be giuen into the hand of the King of Asshur.", "wycliffe": "spekynge these thingis to Ezechye, kyng of Juda, Thi God disseyue not thee, in whom thou tristist, and seist, Jerusalem schal not be youun in to the hond of the kyng of Assiriens.", "rotherham": "Thus, shall ye surely speak unto Hezekiah king of Judah, saying, Let not thy God, in whom, thou, art trusting, beguile thee, saying,—Jerusalem, shall not be given over, into the hand of the king of Assyria.", "darby": "Thus shall ye speak to Hezekiah king of Judah, saying: Let not thyGod, upon whom thou reliest, deceive thee, saying, Jerusalem shall not be delivered into the hand of the king of Assyria.", "twenty": "", "jps": "'Thus shall ye speak to Hezekiah king of Judah, saying: Let not thy G-d in whom thou trustest beguile thee, saying: Jerusalem shall not be given into the hand of the king of Assyria.", "acv": "Thus shall ye speak to Hezekiah king of Judah, saying, Let not thy God in whom thou trust deceive thee, saying, Jerusalem shall not be given into the hand of the king of Assyria.", "anderson": "", "haweis": "", "noyes": "Thus shall ye say to Hezekiah, the king of Judah: Let not thy God, in whom thou trustest, deceive thee, saying, Jerusalem shall not be given into the hand of the king of Assyria.", "webster": "Thus shall ye speak to Hezekiah king of Judah, saying, Let not thy God in whom thou trustest, deceive thee, saying, Jerusalem shall not be given into the hand of the king of Assyria.", "vulgate": "haec dicetis Ezechiae regi Iudae loquentes non te decipiat Deus tuus in quo tu confidis dicens non dabitur Hierusalem in manu regis Assyriorum;", "brenton": "Thus shall ye say to Ezekias king of Judea, Let not thy God, in whom thou trustest, deceive thee, saying, Jerusalem shall not be delivered into the hand of the king of the Assyrians."}}, {"v": 11, "ref": "37:11", "o": "הִנֵּ֣ה אַתָּ֣ה שָׁמַ֗עְתָּ אֲשֶׁ֨ר עָשׂ֜וּ מַלְכֵ֥י אַשּׁ֛וּר לְ/כָל הָ/אֲרָצ֖וֹת לְ/הַחֲרִימָ֑/ם וְ/אַתָּ֖ה תִּנָּצֵֽל", "en": {"kjv": "Behold, thou hast heard what the kings of Assyria have done to all lands by destroying them utterly; and shalt thou be delivered?", "web": "Behold, you have heard what the kings of Assyria have done to all lands, by destroying them utterly. Shall you be delivered?", "bsb": "Surely you have heard what the kings of Assyria have done to all the other countries, devoting them to destruction. Will you then be spared?", "asv": "Behold, thou hast heard what the kings of Assyria have done to all lands, by destroying them utterly: and shalt thou be delivered?", "ylt": "Lo, thou hast heard that which the kings of Asshur have done to all the lands--to devote them--and thou art delivered!", "dra": "Behold thou hast heard all that the kings of the Assyrians have done to all countries which they have destroyed, and canst thou be delivered?", "bbe": "No doubt the story has come to your ears of what the kings of Assyria have done to all lands, putting them to the curse: and will you be kept safe from their fate?", "geneva": "Beholde, thou hast heard what the Kings of Asshur haue done to all lands in destroying them, and shalt thou be deliuered?", "wycliffe": "Lo! thou herdist alle thingis whiche the kynges of Assiriens diden to alle londis whiche thei distrieden; and maist thou be delyuered?", "rotherham": "Lo! thou, thyself, hast heard what the kings of Assyria have done to all the lands in devoting them to destruction,—and shalt, thou, be delivered?", "darby": "Behold, thou hast heard what the kings of Assyria have done to all countries, destroying them utterly; and shalt thou be delivered?", "twenty": "", "jps": "Behold, thou hast heard what the kings of Assyria have done to all lands, by destroying them utterly; and shalt thou be delivered?", "acv": "Behold, thou have heard what the kings of Assyria have done to all lands, by destroying them utterly. And shall thou be delivered?", "anderson": "", "haweis": "", "noyes": "Behold, thou hast heard what the kings of Assyria have done to all the lands; how they have utterly destroyed them. And shalt thou be delivered?", "webster": "Behold, thou hast heard what the kings of Assyria have done to all lands by destroying them utterly; and shalt thou be delivered?", "vulgate": "ecce tu audisti omnia quae fecerunt reges Assyriorum omnibus terris quas subverterunt et tu poteris liberari;", "brenton": "Hast thou not heard what the kings of the Assyrians have done, how they have destroyed the whole earth? and shalt thou be delivered?"}}, {"v": 12, "ref": "37:12", "o": "הַ/הִצִּ֨ילוּ אוֹתָ֜/ם אֱלֹהֵ֤י הַ/גּוֹיִם֙ אֲשֶׁ֣ר הִשְׁחִ֣יתוּ אֲבוֹתַ֔/י אֶת גּוֹזָ֖ן וְ/אֶת חָרָ֑ן וְ/רֶ֥צֶף וּ/בְנֵי עֶ֖דֶן אֲשֶׁ֥ר בִּ/תְלַשָּֽׂר", "en": {"kjv": "Have the gods of the nations delivered them which my fathers have destroyed, as Gozan, and Haran, and Rezeph, and the children of Eden which were in Telassar?", "web": "Have the gods of the nations delivered them, which my fathers have destroyed, Gozan, Haran, Rezeph, and the children of Eden who were in Telassar?", "bsb": "Did the gods of the nations destroyed by my fathers rescue those nations—the gods of Gozan, Haran, and Rezeph, and of the people of Eden in Telassar?", "asv": "Have the gods of the nations delivered them, which my fathers have destroyed, Gozan, and Haran, and Rezeph, and the children of Eden that were in Telassar?", "ylt": "Did the gods of the nations deliver them whom my fathers destroyed--Gozan, and Haran, and Rezeph, and the sons of Eden, who are in Telassar?", "dra": "Have the gods of the nations delivered them whom my fathers have destroyed, Gozam, and Haram, and Reseph, and the children of Eden, that were in Thalassar?", "bbe": "Did the gods of the nations keep safe those on whom my fathers sent destruction, Gozan and Haran and Rezeph, and the children of Eden who were in Telassar?", "geneva": "Haue the gods of the nations deliuered them, which my fathers haue destroyed? as Gozan, and Haran, and Rezeph, and the children of Eden, which were at Telassar?", "wycliffe": "Whethir the goddis of folkis delyuereden hem, whiche my fadris distrieden; Gosan, and Aran, and Reseph, and the sones of Eden, that weren in Thalasar?", "rotherham": "Did the gods of the nations, deliver them, whom my fathers destroyed,—Gozan, and Haran,—and Rezeph, and the sons of Eden, who were in Telassar?", "darby": "Have thegods of the nations which my fathers have destroyed delivered them, Gozan, and Haran, and Rezeph, and the children of Eden that were in Thelassar?", "twenty": "", "jps": "Have the gods of the nations delivered them, which my fathers have destroyed, Gozan, and Haran, and Rezeph, and the children of Eden that were in Telassar?", "acv": "Have the gods of the nations delivered them, which my fathers have destroyed, Gozan, and Haran, and Rezeph, and the sons of Eden who were in Telassar?", "anderson": "", "haweis": "", "noyes": "Did the gods of the nations which my father destroyed, deliver them? Gozan, and Haran, and Rezeph, and the children of Eden in Telassar?", "webster": "Have the gods of the nations delivered them which my fathers have destroyed, [as] Gozan, and Haran, and Rezeph, and the children of Eden who [were] in Telassar?", "vulgate": "numquid eruerunt eos dii gentium quos subverterunt patres mei Gozan et Aran et Reseph et filios Eden qui erant in Thalassar;", "brenton": "Have the gods of the nations which my fathers destroyed delivered them, both Gozan, and Charrhan, and Rapheth, which are in the land of Theemath?"}}, {"v": 13, "ref": "37:13", "o": "אַיֵּ֤ה מֶֽלֶךְ חֲמָת֙ וּ/מֶ֣לֶךְ אַרְפָּ֔ד וּ/מֶ֖לֶךְ לָעִ֣יר סְפַרְוָ֑יִם הֵנַ֖ע וְ/עִוָּֽה", "en": {"kjv": "Where is the king of Hamath, and the king of Arphad, and the king of the city of Sepharvaim, Hena, and Ivah?", "web": "Where is the king of Hamath, and the king of Arpad, and the king of the city of Sepharvaim, of Hena, and Ivvah?’”", "bsb": "Where are the kings of Hamath, Arpad, Sepharvaim, Hena, and Ivvah?’”", "asv": "Where is the king of Hamath, and the king of Arpad, and the king of the city of Sepharvaim, of Hena, and Ivvah?", "ylt": "Where is the king of Hamath, and the king of Arpad, and the king of the city of Sepharvaim, Hena, and Ivvah?'", "dra": "Where is the king of Emath, and the king of Arphad, and the king of the city of Sepharvaim, of Ana, and of Ava?", "bbe": "Where is the king of Hamath, and the king of Arpad, and the king of the town of Sepharvaim, of Hena, and Ivva?", "geneva": "Where is the King of Hamath, and the King of Arpad, and the King of the citie of Sepharuaim, Hena and Iuah?", "wycliffe": "Where is the kyng of Emath, and the kyng of Arphath, and the kyng of the citee of Sepharuaym, and of Ana, and of Aua?", "rotherham": "Where are the king of Hamath, and the king of Arpad, and the king of the city of Sepharvaim,—of Hena, and Ivvah?", "darby": "Where is the king of Hamath, and the king of Arpad, and the king of the city of Sepharvaim, of Hena, and Ivvah?", "twenty": "", "jps": "Where is the king of Hamath, and the king of Arpad, and the king of the city of Sepharvaim, of Hena, and Ivvah?'", "acv": "Where is the king of Hamath, and the king of Arpad, and the king of the city of Sepharvaim, of Hena, and Ivvah?", "anderson": "", "haweis": "", "noyes": "Where is the king of Hamath, and the king of Arphad, and the king of the city of Sepharvaim, of Henah, and of Ivah?", "webster": "Where [is] the king of Hamath, and the king of Arpad, and the king of the city of Sepharvaim, Hena, and Ivah?", "vulgate": "ubi est rex Emath et rex Arfad et rex urbis Seffarvaim Anahe et Ava;", "brenton": "Where are the kings of Emath? and where is the king of Arphath? and where is the king of the city of Eppharuaim, and of Anagugana?"}}, {"v": 14, "ref": "37:14", "o": "וַ/יִּקַּ֨ח חִזְקִיָּ֧הוּ אֶת הַ/סְּפָרִ֛ים מִ/יַּ֥ד הַ/מַּלְאָכִ֖ים וַ/יִּקְרָאֵ֑/הוּ וַ/יַּ֨עַל֙ בֵּ֣ית יְהוָ֔ה וַ/יִּפְרְשֵׂ֥/הוּ חִזְקִיָּ֖הוּ לִ/פְנֵ֥י יְהוָֽה", "en": {"kjv": "And Hezekiah received the letter from the hand of the messengers, and read it: and Hezekiah went up unto the house of the Lord, and spread it before the Lord.", "web": "Hezekiah received the letter from the hand of the messengers and read it. Then Hezekiah went up to Yahweh’s house, and spread it before Yahweh.", "bsb": "So Hezekiah received the letter from the messengers, read it, and went up to the house of the LORD and spread it out before the LORD.", "asv": "And Hezekiah received the letter from the hand of the messengers, and read it; and Hezekiah went up unto the house of Jehovah, and spread it before Jehovah.", "ylt": "And Hezekiah taketh the letters out of the hand of the messengers, and readeth them, and Hezekiah goeth up to the house of Jehovah, and Hezekiah spreadeth it before Jehovah.", "dra": "And Ezechias took the letter from the hand of the messengers, and read it, and went up to the house of the Lord, and Ezechias spread it before the Lord.", "bbe": "And Hezekiah took the letter from the hands of those who had come with it; and after reading it, Hezekiah went up to the house of the Lord, opening the letter there before the Lord,", "geneva": "So Hezekiah receiued the letter of the hand of the messengers and read it, and he went vp into the House of the Lord, and Hezekiah spread it before the Lord.", "wycliffe": "And Ezechie took the bookis fro the hond of messangeris, and redde tho; and he stiede in to the hous of the Lord, and spredde abrood tho bifore the Lord;", "rotherham": "And, when Hezekiah had received the letter at the hand of the messengers, and had read it, then went he up to the house of Yahweh, and Hezekiah spread it out, before Yahweh.", "darby": "And Hezekiah received the letter from the hand of the messengers, and read it; and Hezekiah went up into the house of Jehovah, and spread it before Jehovah.", "twenty": "", "jps": "And Hezekiah received the letter from the hand of the messengers, and read it; and Hezekiah went up unto the house of HaShem, and spread it before HaShem.", "acv": "And Hezekiah received the letter from the hand of the messengers, and read it. And Hezekiah went up to the house of Jehovah, and spread it before Jehovah.", "anderson": "", "haweis": "", "noyes": "And Hezekiah received the letter from the hand of the messengers, and read it. Then he went up to the house of Jehovah, and spread it before Jehovah.", "webster": "And Hezekiah received the letter from the hand of the messengers, and read it: and Hezekiah went up to the house of the LORD, and spread it before the LORD.", "vulgate": "et tulit Ezechias libros de manu nuntiorum et legit eos et ascendit in domum Domini et expandit eos Ezechias coram Domino;", "brenton": "And Ezekias received the letter from the messengers, and read it, and went up to the house of the Lord, and opened it before the Lord."}}, {"v": 15, "ref": "37:15", "o": "וַ/יִּתְפַּלֵּל֙ חִזְקִיָּ֔הוּ אֶל יְהוָ֖ה לֵ/אמֹֽר", "en": {"kjv": "And Hezekiah prayed unto the Lord, saying,", "web": "Hezekiah prayed to Yahweh, saying,", "bsb": "And Hezekiah prayed to the LORD:", "asv": "And Hezekiah prayed unto Jehovah, saying,", "ylt": "And Hezekiah prayeth unto Jehovah, saying,", "dra": "And Ezechias prayed to the Lord, saying:", "bbe": "And he made prayer to the Lord, saying,", "geneva": "And Hezekiah prayed vnto the Lord, saying,", "wycliffe": "and preiede to the Lord,", "rotherham": "And Hezekiah prayed unto Yahweh saying:", "darby": "And Hezekiah prayed to Jehovah, saying,", "twenty": "", "jps": "And Hezekiah prayed unto HaShem, saying:", "acv": "And Hezekiah prayed to Jehovah, saying,", "anderson": "", "haweis": "", "noyes": "And Hezekiah prayed before Jehovah, saying,", "webster": "And Hezekiah prayed to the LORD, saying,", "vulgate": "et oravit Ezechias ad Dominum dicens;", "brenton": "And Ezekias prayed to the Lord, saying,"}}, {"v": 16, "ref": "37:16", "o": "יְהוָ֨ה צְבָא֜וֹת אֱלֹהֵ֤י יִשְׂרָאֵל֙ יֹשֵׁ֣ב הַ/כְּרֻבִ֔ים אַתָּה ה֤וּא הָֽ/אֱלֹהִים֙ לְ/בַדְּ/ךָ֔ לְ/כֹ֖ל מַמְלְכ֣וֹת הָ/אָ֑רֶץ אַתָּ֣ה עָשִׂ֔יתָ אֶת הַ/שָּׁמַ֖יִם וְ/אֶת הָ/אָֽרֶץ", "en": {"kjv": "O Lord of hosts, God of Israel, that dwellest between the cherubims, thou art the God, even thou alone, of all the kingdoms of the earth: thou hast made heaven and earth.", "web": "“Yahweh of Armies, the God of Israel, who is enthroned among the cherubim, you are the God, even you alone, of all the kingdoms of the earth. You have made heaven and earth.", "bsb": "“O LORD of Hosts, God of Israel, enthroned above the cherubim, You alone are God over all the kingdoms of the earth. You made the heavens and the earth.", "asv": "O Jehovah of hosts, the God of Israel, that sittest above the cherubim, thou art the God, even thou alone, of all the kingdoms of the earth; thou hast made heaven and earth.", "ylt": "`Jehovah of Hosts, God of Israel, inhabiting the cherubs, Thou art God Himself--Thyself alone--to all kingdoms of the earth, Thou hast made the heavens and the earth.", "dra": "Lord of hosts, God of Israel who sitteth upon the cherubims, thou alone art the God of all the kingdoms of the earth, thou hast made heaven and earth.", "bbe": "O Lord of armies, the God of Israel, seated between the winged ones, you only are the God of all the kingdoms of the earth; you have made heaven and earth.", "geneva": "O Lord of hostes, God of Israel, which dwellest betweene the Cherubims, thou art very God alone ouer all the kingdomes of the earth: thou hast made the heauen and the earth.", "wycliffe": "and seide, Lord of oostis, God of Israel, that sittist on cherubyn, thou art God aloone of alle the rewmes of erthe; thou madist heuene and erthe.", "rotherham": "O Yahweh of hosts, God of Israel—inhabiting the cherubim, Thou thyself, art GOD, even thou alone, for all the kingdoms of the earth: Thou, didst make the heavens and the earth.", "darby": "Jehovah of hosts, theGod of Israel, who sittest [between] the cherubim, thou, the Same, thou alone art theGod of all the kingdoms of the earth: thou hast made the heavens and the earth.", "twenty": "", "jps": "'O HaShem of hosts, the G-d of Israel, that sittest upon the cherubim, Thou art the G-d, even Thou alone, of all the kingdoms of the earth; Thou hast made heaven and earth.", "acv": "O Jehovah of hosts, the God of Israel, who sit above the cherubim, thou are the God, even thou alone, of all the kingdoms of the earth. Thou have made heaven and earth.", "anderson": "", "haweis": "", "noyes": "O Jehovah of hosts, God of Israel, who sittest between the cherubs, thou alone art the God of all the kingdoms of the earth; thou hast made heaven and earth.", "webster": "O LORD of hosts, God of Israel, that dwellest [between] the cherubim, thou [art] the God, [even] thou alone, of all the kingdoms of the earth: thou hast made heaven and earth.", "vulgate": "Domine exercituum Deus Israhel qui sedes super cherubin tu es Deus solus omnium regnorum terrae tu fecisti caelum et terram;", "brenton": "O Lord of hosts, God of Israel, who sittest upon the cherubs, thou alone art the God of every kingdom of the world: thou hast made heaven and earth."}}, {"v": 17, "ref": "37:17", "o": "הַטֵּ֨ה יְהוָ֤ה אָזְנְ/ךָ֙ וּֽ/שְׁמָ֔ע פְּקַ֧ח יְהוָ֛ה עֵינֶ֖/ךָ וּ/רְאֵ֑ה וּ/שְׁמַ֗ע אֵ֚ת כָּל דִּבְרֵ֣י סַנְחֵרִ֔יב אֲשֶׁ֣ר שָׁלַ֔ח לְ/חָרֵ֖ף אֱלֹהִ֥ים חָֽי", "en": {"kjv": "Incline thine ear, O Lord, and hear; open thine eyes, O Lord, and see: and hear all the words of Sennacherib, which hath sent to reproach the living God.", "web": "Turn your ear, Yahweh, and hear. Open your eyes, Yahweh, and behold. Hear all of the words of Sennacherib, who has sent to defy the living God.", "bsb": "Incline Your ear, O LORD, and hear; open Your eyes, O LORD, and see. Listen to all the words that Sennacherib has sent to defy the living God.", "asv": "Incline thine ear, O Jehovah, and hear; open thine eyes, O Jehovah, and see; and hear all the words of Sennacherib, who hath sent to defy the living God.", "ylt": "Incline, O Jehovah, Thine ear, and hear; open, O Jehovah, Thine eyes and see; and hear Thou all the words of Sennacherib that he hath sent to reproach the living God.", "dra": "Incline, O Lord, thy ear, and hear: open, O Lord, thy eyes, and see, and hear all the words of Sennacherib, which he hath sent to blaspheme the living God.", "bbe": "Let your ear be turned to us, O Lord; let your eyes be open, O Lord, and see: take note of all the words of Sennacherib who has sent men to say evil against the living God.", "geneva": "Encline thine eare, O Lord, and heare: open thine eyes, O Lord, and see, and heare all the wordes of Saneherib, who hath sent to blaspheme the liuing God.", "wycliffe": "Lord, bowe doun thin eere, and here; Lord, open thin iyen, and se; and here thou alle the wordis of Sennacherib, whiche he sente for to blasfeme lyuynge God.", "rotherham": "Bow down, O Yahweh, thine ear—and hear, Open, O Yahweh, thine eyes—and see,—Yea hear thou all the words of Sennacherib, who hath sent—to reproach a Living God.", "darby": "Incline thine ear, O Jehovah, and hear; open, Jehovah, thine eyes, and see; and hear all the words of Sennacherib, who hath sent to reproach the livingGod.", "twenty": "", "jps": "Incline Thine ear, O HaShem, and hear; open Thine eyes, O HaShem, and see; and hear all the words of Sennacherib, who hath sent to taunt the living G-d.", "acv": "Incline thine ear, O Jehovah, and hear. Open thine eyes, O Jehovah, and see, and hear all the words of Sennacherib, who has sent to defy the living God.", "anderson": "", "haweis": "", "noyes": "Incline thine ear, O Jehovah, and hear; open thine eyes, O Jehovah, and see; and hear all the words of Sennacherib, which he hath sent to reproach the living God.", "webster": "Incline thy ear, O LORD, and hear; open thy eyes, O LORD, and see: and hear all the words of Sennacherib, who hath sent to reproach the living God.", "vulgate": "inclina Domine aurem tuam et audi aperi Domine oculos tuos et vide et audi omnia verba Sennacherib quae misit ad blasphemandum Deum viventem;", "brenton": "Incline thine ear, O Lord, hearken, O Lord; open thine eyes, O Lord, look, O Lord: and behold the words of Sennacherim, which he has sent to reproach the living God."}}, {"v": 18, "ref": "37:18", "o": "אָמְנָ֖ם יְהוָ֑ה הֶחֱרִ֜יבוּ מַלְכֵ֥י אַשּׁ֛וּר אֶת כָּל הָ/אֲרָצ֖וֹת וְ/אֶת אַרְצָֽ/ם", "en": {"kjv": "Of a truth, Lord, the kings of Assyria have laid waste all the nations, and their countries,", "web": "Truly, Yahweh, the kings of Assyria have destroyed all the countries and their land,", "bsb": "Truly, O LORD, the kings of Assyria have laid waste all these countries and their lands.", "asv": "Of a truth, Jehovah, the kings of Assyria have laid waste all the countries, and their land,", "ylt": "`Truly, O Jehovah, kings of Asshur have laid waste all the lands and their land,", "dra": "For of a truth, O Lord, the kings of the Assyrians have laid waste lands, and their countries.", "bbe": "Truly, O Lord, the kings of Assyria have made waste all the nations and their lands,", "geneva": "Trueth it is, O Lord, that the Kings of Asshur haue destroyed all lands, and their countrey,", "wycliffe": "For verili, Lord, the kyngis of Assiriens maden londis dissert, and the cuntreis of tho, and yauen the goddis of tho to fier;", "rotherham": "Of a truth, O Yahweh,—the kings of Assyria have devoted to destruction all the countries, and their land;", "darby": "Of a truth, Jehovah, the kings of Assyria have laid waste all the lands, and their countries,", "twenty": "", "jps": "Of a truth, HaShem, the kings of Assyria have laid waste all the countries, and their land,", "acv": "Of a truth, Jehovah, the kings of Assyria have laid waste all the countries, and their land,", "anderson": "", "haweis": "", "noyes": "In truth, O Jehovah, the kings of Assyria have destroyed all the nations, and their lands,", "webster": "Of a truth, LORD, the kings of Assyria have laid waste all the nations, and their countries,", "vulgate": "vere enim Domine desertas fecerunt reges Assyriorum terras et regiones earum;", "brenton": "For of a truth, Lord, the kings of the Assyrians have laid waste the whole world, and the countries thereof,"}}, {"v": 19, "ref": "37:19", "o": "וְ/נָתֹ֥ן אֶת אֱלֹהֵי/הֶ֖ם בָּ/אֵ֑שׁ כִּי֩ לֹ֨א אֱלֹהִ֜ים הֵ֗מָּה כִּ֣י אִם מַעֲשֵׂ֧ה יְדֵֽי אָדָ֛ם עֵ֥ץ וָ/אֶ֖בֶן וַֽ/יְאַבְּדֽוּ/ם", "en": {"kjv": "And have cast their gods into the fire: for they were no gods, but the work of men’s hands, wood and stone: therefore they have destroyed them.", "web": "and have cast their gods into the fire; for they were no gods, but the work of men’s hands, wood and stone; therefore they have destroyed them.", "bsb": "They have cast their gods into the fire and destroyed them, for they were not gods, but only wood and stone—the work of human hands.", "asv": "and have cast their gods into the fire: for they were no gods, but the work of men’s hands, wood and stone; therefore they have destroyed them.", "ylt": "so as to put their gods into fire--for they are no gods, but work of the hands of man, wood and stone--and they destroy them.", "dra": "And they have cast their gods into the fire, for they were not gods, but the works of men's hands, of wood and stone: and they broke them in pieces.", "bbe": "And have given their gods to the fire: for they were no gods, but wood and stone, the work of men's hands; so they have given them to destruction.", "geneva": "And haue cast their gods in ye fire: for they were no gods, but the worke of mans hands, euen wood or stone: therefore they destroyed them.", "wycliffe": "for thei weren not goddis, but the werkis of mennus hondis, trees and stoonys; and thei al to-braken tho goddis.", "rotherham": "and have put their gods in the fire,—for, no-gods, were they, but the work of the hands of men wood and stone and so they destroyed them.", "darby": "and have cast theirgods into the fire; for they were nogods, but the work of men's hands, wood and stone; and they have destroyed them.", "twenty": "", "jps": "and have cast their gods into the fire; for they were no gods, but the work of men's hands, wood and stone; therefore they have destroyed them.", "acv": "and have cast their gods into the fire. For they were no gods, but the work of men's hands, wood and stone. Therefore they have destroyed them.", "anderson": "", "haweis": "", "noyes": "and have cast their gods into the fire; for they were not gods, but the work of men’s hands, wood and stone; and they have destroyed them.", "webster": "And have cast their gods into the fire: for they [were] no gods, but the work of men's hands, wood and stone: therefore they have destroyed them.", "vulgate": "et dederunt deos earum igni non enim erant dii sed opera manuum hominum lignum et lapis et comminuerunt eos;", "brenton": "and have cast their idols into the fire: for, they were no gods, but the work of men's hands, wood and stone; and they have cast them away."}}, {"v": 20, "ref": "37:20", "o": "וְ/עַתָּה֙ יְהוָ֣ה אֱלֹהֵ֔י/נוּ הוֹשִׁיעֵ֖/נוּ מִ/יָד֑/וֹ וְ/יֵֽדְעוּ֙ כָּל מַמְלְכ֣וֹת הָ/אָ֔רֶץ כִּֽי אַתָּ֥ה יְהוָ֖ה לְ/בַדֶּֽ/ךָ", "en": {"kjv": "Now therefore, O Lord our God, save us from his hand, that all the kingdoms of the earth may know that thou art the Lord, even thou only.", "web": "Now therefore, Yahweh our God, save us from his hand, that all the kingdoms of the earth may know that you are Yahweh, even you only.”", "bsb": "And now, O LORD our God, save us from his hand, so that all the kingdoms of the earth may know that You alone, O LORD, are God.”", "asv": "Now therefore, O Jehovah our God, save us from his hand, that all the kingdoms of the earth may know that thou art Jehovah, even thou only.", "ylt": "And now, Jehovah our God, save us from his hand, and all kingdoms of the earth do know that Thou art Jehovah, Thyself alone.'", "dra": "And now, O Lord our God, save us out of his hand: and let all the kingdoms of the earth know, that thou only art the Lord.", "bbe": "But now, O Lord our God, give us salvation from his hand, so that it may be clear to all the kingdoms of the earth that you, and you only, are the Lord.", "geneva": "Nowe therefore, O Lord our God, saue thou vs out of his hand, that all the kingdomes of the earth may knowe, that thou onely art the Lord.", "wycliffe": "And now, oure Lord God, saue thou vs fro the hond of hym; and alle rewmes of erthe knowe, that thou art Lord God aloone.", "rotherham": "Now, therefore, O Yahweh our God, save us, out of his hand,—That all the kingdoms of the earth, may know, That, thou, art Yahweh, thou alone.", "darby": "And now, Jehovah ourGod, save us out of his hand, that all the kingdoms of the earth may know that thou art Jehovah, thou only.", "twenty": "", "jps": "Now therefore, O HaShem our G-d, save us from his hand, that all the kingdoms of the earth may know that Thou art HaShem, even Thou only.'", "acv": "Now therefore, O Jehovah our God, save us from his hand, that all the kingdoms of the earth may know that thou are Jehovah, even thou only.", "anderson": "", "haweis": "", "noyes": "But do thou, O Jehovah, our God, save us from his hand, that all the kingdoms of the earth may know that thou alone art Jehovah.", "webster": "Now therefore, O LORD our God, save us from his hand, that all the kingdoms of the earth may know that thou [art] the LORD, [even] thou only.", "vulgate": "et nunc Domine Deus noster salva nos de manu eius et cognoscant omnia regna terrae quia tu es Dominus solus;", "brenton": "But now, O Lord our God, deliver us from his hands, that every kingdom of the earth may know that thou art God alone."}}, {"v": 21, "ref": "37:21", "o": "וַ/יִּשְׁלַח֙ יְשַֽׁעְיָ֣הוּ בֶן אָמ֔וֹץ אֶל חִזְקִיָּ֖הוּ לֵ/אמֹ֑ר כֹּֽה אָמַ֤ר יְהוָה֙ אֱלֹהֵ֣י יִשְׂרָאֵ֔ל אֲשֶׁר֙ הִתְפַּלַּ֣לְתָּ אֵלַ֔/י אֶל סַנְחֵרִ֖יב מֶ֥לֶךְ אַשּֽׁוּר", "en": {"kjv": "Then Isaiah the son of Amoz sent unto Hezekiah, saying, Thus saith the Lord God of Israel, Whereas thou hast prayed to me against Sennacherib king of Assyria:", "web": "Then Isaiah the son of Amoz sent to Hezekiah, saying, “Thus says Yahweh, the God of Israel, ‘Because you have prayed to me against Sennacherib king of Assyria,", "bsb": "Then Isaiah son of Amoz sent a message to Hezekiah: “This is what the LORD, the God of Israel, says: Because you have prayed to Me concerning Sennacherib king of Assyria,", "asv": "Then Isaiah the son of Amoz sent unto Hezekiah, saying, Thus saith Jehovah, the God of Israel, Whereas thou hast prayed to me against Sennacherib king of Assyria,", "ylt": "And Isaiah son of Amoz sendeth unto Hezekiah, saying, `Thus said Jehovah, God of Israel, That which thou hast prayed unto me concerning Sennacherib king of Asshur--", "dra": "And Isaiah the son of Amos sent to Ezechias, saying: Thus saith the Lord the God of Israel: For the prayer thou hast made to me concerning Sennacherib the king of the Assyrians:", "bbe": "Then Isaiah, the son of Amoz, sent to Hezekiah, saying, The Lord, the God of Israel, says, The prayer you have made to me against Sennacherib, king of Assyria, has come to my ears.", "geneva": "Then Isaiah the sonne of Amoz sent vnto Hezekiah, saying, Thus sayth the Lord God of Israel, Because thou hast prayed vnto me, concerning Saneherib king of Asshur,", "wycliffe": "And Isaie, the sone of Amos, sente to Ezechie, and seide, The Lord God of Israel seith these thingis, For whiche thingis thou preidist me of Sennacherib, the kyng of Assiriens,", "rotherham": "Then Isaiah son of Amoz sent unto Hezekiah saying,—Thus, saith Yahweh, God of Israel, In that thou hast prayed unto me concerning Sennacherib king of Assyria,", "darby": "And Isaiah the son of Amoz sent to Hezekiah, saying, Thus saith Jehovah theGod of Israel, Whereas thou hast prayed to me concerning Sennacherib king of Assyria,", "twenty": "", "jps": "Then Isaiah the son of Amoz sent unto Hezekiah, saying: 'Thus saith HaShem, the G-d of Israel: Whereas thou hast prayed to Me against Sennacherib king of Assyria,", "acv": "Then Isaiah the son of Amoz sent to Hezekiah, saying, Thus says Jehovah, the God of Israel, Whereas thou have prayed to me against Sennacherib king of Assyria,", "anderson": "", "haweis": "", "noyes": "Then Isaiah, the son of Amoz, sent to Hezekiah, saying, Thus saith Jehovah, the God of Israel: Whereas thou hast prayed to me on account of Sennacherib, the king of Assyria,", "webster": "Then Isaiah the son of Amoz sent to Hezekiah, saying, Thus saith the LORD God of Israel, Whereas thou hast prayed to me against Sennacherib king of Assyria:", "vulgate": "et misit Isaias filius Amos ad Ezechiam dicens haec dicit Dominus Deus Israhel pro quibus rogasti me de Sennacherib rege Assyriorum;", "brenton": "And Esaias the son of Amos was sent to Ezekias, and said to him, Thus saith the Lord, the God of Israel, I have heard thy prayer to me concerning Sennacherim king of the Assyrians."}}, {"v": 22, "ref": "37:22", "o": "זֶ֣ה הַ/דָּבָ֔ר אֲשֶׁר דִּבֶּ֥ר יְהוָ֖ה עָלָ֑י/ו בָּזָ֨ה לְ/ךָ֜ לָעֲגָ֣ה לְ/ךָ֗ בְּתוּלַת֙ בַּת צִיּ֔וֹן אַחֲרֶ֨י/ךָ֙ רֹ֣אשׁ הֵנִ֔יעָה בַּ֖ת יְרוּשָׁלִָֽם", "en": {"kjv": "This is the word which the Lord hath spoken concerning him; The virgin, the daughter of Zion, hath despised thee, and laughed thee to scorn; the daughter of Jerusalem hath shaken her head at thee.", "web": "this is the word which Yahweh has spoken concerning him. The virgin daughter of Zion has despised you and ridiculed you. The daughter of Jerusalem has shaken her head at you.", "bsb": "this is the word that the LORD has spoken against him: ‘The Virgin Daughter of Zion despises you and mocks you; the Daughter of Jerusalem shakes her head behind you.", "asv": "this is the word which Jehovah hath spoken concerning him: The virgin daughter of Zion hath despised thee and laughed thee to scorn; the daughter of Jerusalem hath shaken her head at thee.", "ylt": "this is the word that Jehovah spake concerning him: Trampled on thee, laughed at thee, Hath the virgin daughter of Zion, Behind thee shaken the head hath the daughter of Jerusalem.", "dra": "This is the word which the Lord hath spoken of him: The virgin the daughter of Sion hath despised thee, and laughed thee to scorn: the daughter of Jerusalem hath wagged the head after thee.", "bbe": "This is the word which the Lord has said about him: In the eyes of the virgin daughter of Zion you are shamed and laughed at; the daughter of Jerusalem has made sport of you.", "geneva": "This is the worde that the Lord hath spoken against him, the virgine, the daughter of Zion, hath despised thee, and laughed thee to scorne: the daughter of Ierusalem, hath shaken her head at thee.", "wycliffe": "this is the word which the Lord spak on hym, Thou virgyn, the douyter of Sion, he dispiside thee, he scornede thee; thou virgyn, the douyter of Jerusalem, he moued his heed aftir thee.", "rotherham": "this, is the word which Yahweh hath spoken concerning him,—The virgin daughter of Zion, laugheth thee to scorn—mocketh thee, The daughter of Jerusalem after thee doth wag her head,", "darby": "this is the word which Jehovah hath spoken against him: The virgin-daughter of Zion despiseth thee, laugheth thee to scorn; the daughter of Jerusalem shaketh her head at thee.", "twenty": "", "jps": "this is the word which HaShem hath spoken concerning him: The virgin daughter of Zion hath despised thee and laughed thee to scorn; the daughter of Jerusalem hath shaken her head at thee.", "acv": "this is the word which Jehovah has spoken concerning him: The virgin daughter of Zion has despised thee and laughed thee to scorn. The daughter of Jerusalem has shaken her head at thee.", "anderson": "", "haweis": "", "noyes": "This is the word which Jehovah hath spoken against him. The virgin, the daughter of Zion, despiseth thee; she laugheth thee to scorn; The daughter of Jerusalem shaketh her head after thee.", "webster": "This [is] the word which the LORD hath spoken concerning him; The virgin, the daughter of Zion, hath despised thee, [and] derided thee; the daughter of Jerusalem hath shaken her head at thee.", "vulgate": "hoc est verbum quod locutus est Dominus super eum despexit te subsannavit te virgo filia Sion post te caput movit filia Hierusalem;", "brenton": "This is the word which God has spoken concerning him; The virgin daughter of Sion has despised thee, and mocked thee; the daughter of Jerusalem has shaken her head at thee."}}, {"v": 23, "ref": "37:23", "o": "אֶת מִ֤י חֵרַ֨פְתָּ֙ וְ/גִדַּ֔פְתָּ וְ/עַל מִ֖י הֲרִימ֣וֹתָה קּ֑וֹל וַ/תִּשָּׂ֥א מָר֛וֹם עֵינֶ֖י/ךָ אֶל קְד֥וֹשׁ יִשְׂרָאֵֽל", "en": {"kjv": "Whom hast thou reproached and blasphemed? and against whom hast thou exalted thy voice, and lifted up thine eyes on high? even against the Holy One of Israel.", "web": "Whom have you defied and blasphemed? Against whom have you exalted your voice and lifted up your eyes on high? Against the Holy One of Israel.", "bsb": "Whom have you taunted and blasphemed? Against whom have you raised your voice and lifted your eyes in pride? Against the Holy One of Israel!", "asv": "Whom hast thou defied and blasphemed? and against whom hast thou exalted thy voice and lifted up thine eyes on high? even against the Holy One of Israel.", "ylt": "Whom hast thou reproached and reviled? And against whom lifted up the voice? Yea, thou dost lift up on high thine eyes Against the Holy One of Israel.", "dra": "Whom hast thou reproached, and whom hast thou blasphemed, and against whom hast thou exalted thy voice, and lifted up thy eyes on high? Against the Holy One of Israel.", "bbe": "Against whom have you said evil and bitter things? and against whom has your voice been loud and your eyes lifted up? even against the Holy One of Israel.", "geneva": "Whome hast thou railed on and blasphemed? and against whome hast thou exalted thy voyce, and lifted vp thine eyes on hie? euen against the holy one of Israel.", "wycliffe": "Whom despisist thou, and whom blasfemedist thou? and on whom reisidist thou thi vois, and reisidist the hiynesse of thin iyen?", "rotherham": "Whom, hast thou reproached and insulted? And, against whom, hast thou lifted high thy voice? Yea thou hast proudly raised thine eyes, against the Holy One of Israel.", "darby": "Whom hast thou reproached and blasphemed? and against whom hast thou exalted the voice? Against the Holy One of Israel hast thou lifted up thine eyes on high.", "twenty": "", "jps": "Whom hast thou taunted and blasphemed? And against whom hast thou exalted thy voice? Yea, thou hast lifted up thine eyes on high, even against the Holy One of Israel!", "acv": "Whom have thou defied and blasphemed? And against whom have thou exalted thy voice and lifted up thine eyes on high? Even against the Holy One of Israel.", "anderson": "", "haweis": "", "noyes": "Whom hast thou reproached, and reviled, And against whom hast thou exalted thy voice, And lifted up thine eyes on high? Against the Holy One of Israel.", "webster": "Whom hast thou reproached and blasphemed; and against whom hast thou exalted [thy] voice, and lifted thy eyes on high? [even] against the Holy One of Israel.", "vulgate": "cui exprobrasti et quem blasphemasti et super quem exaltasti vocem et levasti altitudinem oculorum tuorum ad Sanctum Israhel;", "brenton": "Whom hast thou reproached and provoked? and against whom hast thou lifted up thy voice? and hast thou not lifted up thine eyes on high against the Holy One of Israel?"}}, {"v": 24, "ref": "37:24", "o": "בְּ/יַ֣ד עֲבָדֶי/ךָ֮ חֵרַ֣פְתָּ אֲדֹנָ/י֒ וַ/תֹּ֗אמֶר בְּ/רֹ֥ב רִכְבִּ֛/י אֲנִ֥י עָלִ֛יתִי מְר֥וֹם הָרִ֖ים יַרְכְּתֵ֣י לְבָנ֑וֹן וְ/אֶכְרֹ֞ת קוֹמַ֤ת אֲרָזָי/ו֙ מִבְחַ֣ר בְּרֹשָׁ֔י/ו וְ/אָבוֹא֙ מְר֣וֹם קִצּ֔/וֹ יַ֖עַר כַּרְמִלּֽ/וֹ", "en": {"kjv": "By thy servants hast thou reproached the Lord, and hast said, By the multitude of my chariots am I come up to the height of the mountains, to the sides of Lebanon; and I will cut down the tall cedars thereof, and the choice fir trees thereof: and I will enter into the height of his border, and the forest of his Carmel.", "web": "By your servants, have you defied the Lord, and have said, “With the multitude of my chariots I have come up to the height of the mountains, to the innermost parts of Lebanon. I will cut down its tall cedars and its choice fir trees. I will enter into its farthest height, the forest of its fruitful field.", "bsb": "Through your servants you have taunted the Lord, and you have said: “With my many chariots I have ascended to the heights of the mountains, to the remote peaks of Lebanon. I have cut down its tallest cedars, the finest of its cypresses. I have reached its farthest heights, the densest of its forests.", "asv": "By thy servants hast thou defied the Lord, and hast said, With the multitude of my chariots am I come up to the height of the mountains, to the innermost parts of Lebanon; and I will cut down the tall cedars thereof, and the choice fir-trees thereof; and I will enter into its farthest height, the forest of its fruitful field;", "ylt": "By the hand of thy servants Thou hast reviled the Lord, and sayest: In the multitude of my chariots I have come up to a high place of hills, The sides of Lebanon, And I cut down the height of its cedars, The choice of its firs, And I enter the high place of its extremity, The forest of its Carmel.", "dra": "By the hand of thy servants thou hast reproached the Lord: and hast said: With the multitude of my chariots I have gone up to the height of the mountains, to the top of Libanus: and I will cut down its tall cedars, and its choice fir trees, and will enter to the top of its height, to the forest of its Carmel.", "bbe": "You have sent your servants with evil words against the Lord, and have said, With all my war-carriages I have come up to the top of the mountains, to the inmost parts of Lebanon; and its tall cedars will be cut down, and the best trees of its woods: I will come up into his highest places, into his thick woods.", "geneva": "By thy seruants hast thou railed on the Lord, and sayd, By the multitude of my charets I am come vp to the top of the mountaines to the sides of Lebanon, and will cut downe the hie cedars thereof, and the faire firre trees thereof, and I will goe vp to the heightes of his top and to the forest of his fruitfull places.", "wycliffe": "To the hooli of Israel. Bi the hond of thi seruauntis thou dispisidist the Lord, and seidist, In the multitude of my cartis Y stiede on the hiynesses of hillis, on the yockis of Liban; and Y schal kitte doun the hiy thingis of cedris therof, and the chosun beechis therof; and Y schal entre in to the hiynesse of the cop therof, in to the forest of Carmele therof.", "rotherham": "Through thy servants, thou hast reproached My Lord and hast said,—With my multitude of chariots, have I ascended The height of the mountains The recesses of Lebanon, That I may cut down Its tallest cedars Its choicest firs, That I may enter Its highest summit, Its thick garden forest:", "darby": "By thy servants thou hast reproached the Lord, and hast said, With the multitude of my chariots am I come up to the height of the mountains, to the recesses of Lebanon; and I will cut down its tall cedars, the choice of its cypresses; and I will enter into its furthest height, [into] the forest of its fruitful field.", "twenty": "", "jps": "By thy servants hast thou taunted the L-rd, and hast said: With the multitude of my chariots am I come up to the height of the mountains, to the innermost parts of Lebanon; and I have cut down the tall cedars thereof, and the choice cypress-trees thereof; and I have entered into his farthest height, the forest of his fruitful field.", "acv": "By thy servants thou have defied the Lord, and have said, With the multitude of my chariots I have come up to the height of the mountains, to the innermost parts of Lebanon. And I will cut down the tall cedars of it, and the choice fir trees of it, and I will enter into its farthest height, the forest of its fruitful field.", "anderson": "", "haweis": "", "noyes": "By thy servants hast thou reproached the Lord, and said: \"With the multitude of my chariots have I ascended the heights of the mountains, the extremities of Lebanon; I have cut down its tall cedars, and its choice cypress-trees; I have come to its utmost height, to its garden forest.", "webster": "By thy servants hast thou reproached the Lord, and hast said, By the multitude of my chariots have I come up to the hight of the mountains, to the sides of Lebanon; and I will cut down its tall cedars, [and] its choice fir-trees: and I will enter into the hight of its border, [and] the forest of its Carmel.", "vulgate": "in manu servorum tuorum exprobrasti Domino et dixisti in multitudine quadrigarum mearum ego ascendi altitudinem montium iuga Libani et succidam excelsa cedrorum eius electas abietes illius et introibo altitudinem summitatis eius saltum Carmeli eius;", "brenton": "For thou hast reproached the Lord by messengers; for thou hast said, With the multitude of chariots have I ascended to the height of mountains, and to the sides of Libanus; and I have cropped the height of his cedars and the beauty of his cypresses; and I entered into the height of the forest region:"}}, {"v": 25, "ref": "37:25", "o": "אֲנִ֥י קַ֖רְתִּי וְ/שָׁתִ֣יתִי מָ֑יִם וְ/אַחְרִב֙ בְּ/כַף פְּעָמַ֔/י כֹּ֖ל יְאֹרֵ֥י מָצֽוֹר", "en": {"kjv": "I have digged, and drunk water; and with the sole of my feet have I dried up all the rivers of the besieged places.", "web": "I have dug and drunk water, and with the sole of my feet I will dry up all the rivers of Egypt.”", "bsb": "I have dug wells and drunk foreign waters. With the soles of my feet I have dried up all the streams of Egypt.”", "asv": "I have digged and drunk water, and with the sole of my feet will I dry up all the rivers of Egypt.", "ylt": "I--I have dug and drunk waters, And I dry up with the sole of my steps All floods of a bulwark.", "dra": "I have digged, and drunk water, and have dried up with the sole of my foot, all the rivers shut up in banks.", "bbe": "I have made water-holes and taken their waters, and with my foot I have made all the rivers of Egypt dry.", "geneva": "I haue digged and drunke the waters, and with the plant of my feete haue I dryed all the riuers closed in.", "wycliffe": "Y diggide, and drank watir; and Y made drie with the step of my foot all the strondis of feeldis.", "rotherham": "I, have digged, and drunk waters,—That I may dry up, with the soles of my feet, all the Nile-streams of Egypt.", "darby": "I have digged and drunk water; and with the sole of my feet have I dried up all the streams of Matsor.", "twenty": "", "jps": "I have digged and drunk water, and with the sole of my feet have I dried up all the rivers of Egypt.", "acv": "I have dug and drunk water, and with the sole of my feet I will dry up all the rivers of Egypt.", "anderson": "", "haweis": "", "noyes": "I have digged and drunk water, And with the sole of my feet will I dry up all the rivers of Egypt.\"", "webster": "I have digged, and drank water; and with the sole of my feet have I dried up all the rivers of the besieged places.", "vulgate": "ego fodi et bibi aquam et exsiccavi vestigio pedis mei omnes rivos aggerum;", "brenton": "and I have made a bridge, and dried up the waters, and every pool of water."}}, {"v": 26, "ref": "37:26", "o": "הֲ/לֽוֹא שָׁמַ֤עְתָּ לְ/מֵֽ/רָחוֹק֙ אוֹתָ֣/הּ עָשִׂ֔יתִי מִ֥/ימֵי קֶ֖דֶם וִ/יצַרְתִּ֑י/הָ עַתָּ֣ה הֲבֵאתִ֔י/הָ וּ/תְהִ֗י לְ/הַשְׁא֛וֹת גַּלִּ֥ים נִצִּ֖ים עָרִ֥ים בְּצֻרֽוֹת", "en": {"kjv": "Hast thou not heard long ago, how I have done it; and of ancient times, that I have formed it? now have I brought it to pass, that thou shouldest be to lay waste defenced cities into ruinous heaps.", "web": "Have you not heard how I have done it long ago, and formed it in ancient times? Now I have brought it to pass, that it should be yours to destroy fortified cities, turning them into ruinous heaps.", "bsb": "Have you not heard? Long ago I ordained it; in days of old I planned it. Now I have brought it to pass, that you should crush fortified cities into piles of rubble.", "asv": "Hast thou not heard how I have done it long ago, and formed it of ancient times? now have I brought it to pass, that it should be thine to lay waste fortified cities into ruinous heaps.", "ylt": "Hast thou not heard from afar? --it I did, From days of old--that I formed it. Now, I have brought it in, And it is to make desolate, Ruinous heaps--fenced cities,", "dra": "Hast thou not heard what I have done to him of old? from the days of old I have formed it: and now I have brought it to effect: and it hath come to pass that hills fighting together, and fenced cities should be destroyed.", "bbe": "Has it not come to your ears how I did it long before, purposing it in times long past? Now I have given effect to my design, so that by you strong towns might be turned into masses of broken walls.", "geneva": "Hast thou not heard howe I haue of olde time made it, and haue formed it long ago? and should I now bring it, that it should be destroyed, and layde on ruinous heapes, as cities defensed?", "wycliffe": "Whether thou, Sennacherib, herdist not what thingis Y dide sum tyme? Fro elde daies Y fourmyde that thing, and now Y haue brouyt; and it is maad in to drawyng vp bi the roote of litle hillis fiytynge togidere, and of strong citees.", "rotherham": "Hast thou not heard—That, long ago, that, is what I appointed, And from days of old, devised? Now, have I brought it to pass, That thou mightest Serve to lay waste, in desolate ruins, fortified cities;", "darby": "Hast thou not heard that long ago I did it, and that from ancient days I formed it? Now have I brought it to pass, that thou shouldest lay waste fortified cities [into] ruinous heaps.", "twenty": "", "jps": "Hast thou not heard? Long ago I made it, in ancient times I fashioned it; now have I brought it to pass, yea, it is done; that fortified cities should be laid waste into ruinous heaps.", "acv": "Have thou not heard how I have done it long ago, and formed it of ancient times? Now I have brought it to pass, that it should be thine to lay waste fortified cities into ruinous heaps.", "anderson": "", "haweis": "", "noyes": "Hast thou not heard, that of old I ordained it, And from ancient times purposed it? Now have I brought it to pass, That thou shouldst convert fortified cities into ruinous heaps.", "webster": "Hast thou not heard long ago, [how] I have done it; [and] of ancient times, that I have formed it? now have I brought it to pass, that thou shouldst be to lay waste fortified cities [into] ruinous heaps.", "vulgate": "numquid non audisti quae olim fecerim ei ex diebus antiquis ego plasmavi illud et nunc adduxi et factum est in eradicationem collium conpugnantium et civitatum munitarum;", "brenton": "Hast thou not heard of these things which I did of old? I appointed them from ancient times; but now have I manifested my purpose of desolating nations in their strong holds, and them that dwell in strong cities."}}, {"v": 27, "ref": "37:27", "o": "וְ/יֹֽשְׁבֵי/הֶן֙ קִצְרֵי יָ֔ד חַ֖תּוּ וָ/בֹ֑שׁוּ הָי֞וּ עֵ֤שֶׂב שָׂדֶה֙ וִ֣/ירַק דֶּ֔שֶׁא חֲצִ֣יר גַּגּ֔וֹת וּ/שְׁדֵמָ֖ה לִ/פְנֵ֥י קָמָֽה", "en": {"kjv": "Therefore their inhabitants were of small power, they were dismayed and confounded: they were as the grass of the field, and as the green herb, as the grass on the housetops, and as corn blasted before it be grown up.", "web": "Therefore their inhabitants had little power. They were dismayed and confounded. They were like the grass of the field, and like the green herb, like the grass on the housetops, and like a field before its crop has grown.", "bsb": "Therefore their inhabitants, devoid of power, are dismayed and ashamed. They are like plants in the field, tender green shoots, grass on the rooftops, scorched before it is grown.", "asv": "Therefore their inhabitants were of small power, they were dismayed and confounded; they were as the grass of the field, and as the green herb, as the grass on the housetops, and as a field of grain before it is grown up.", "ylt": "And their inhabitants are feeble-handed, They were broken down, and are dried up. They have been the herb of the field, And the greenness of the tender grass, Grass of the roofs, And blasted corn, before it hath risen up.", "dra": "The inhabitants of them were weak of hand, they trembled, and were confounded: they became like the grass of the field, and the herb of the pasture, and like the grass of the housetops, which withered before it was ripe.", "bbe": "This is why their townsmen had no power, they were broken and put to shame; they were like the grass of the field, or a green plant; like the grass on the house-tops, which a cold wind makes waste.", "geneva": "Whose inhabitants haue small power, and are afrayd and confounded: they are like the grasse of the field and greene herbe, or grasse on the house tops, or corne blassed afore it be growen.", "wycliffe": "The dwelleris of tho citees trembliden togidere with hond maad schort, and ben aschamed; thei ben maad as hei of the feeld, and the gras of lesewe, and as erbe of roouys, that driede vp bifore that it wexide ripe.", "rotherham": "And their inhabitants, being powerless, were overthrown and put to shame—They became—Grass of the field and Young herbage, Grass on housetops, and Seed parched before it came up.", "darby": "And their inhabitants were powerless, they were dismayed and put to shame; they were [as] the grass of the field and the green herb, [as] the grass on the housetops, and grain blighted before it be grown up.", "twenty": "", "jps": "Therefore their inhabitants were of small power, they were dismayed and confounded; they were as the grass of the field, and as the green herb, as the grass on the housetops, and as a field of corn before it is grown up.", "acv": "Therefore their inhabitants were of small power. They were dismayed and confounded. They were as the grass of the field, and as the green herb. As the grass on the housetops, and as a field of grain before it is grown up.", "anderson": "", "haweis": "", "noyes": "Therefore were their inhabitants of little strength; They were dismayed and confounded; They were as the grass of the field, and the green herb; As grass upon the house-top, and as corn blasted, before it is grown up.", "webster": "Therefore their inhabitants [were] of small power, they were dismayed and confounded: they were [as] the grass of the field, and [as] the green herb, [as] the grass on the house-tops, and [as corn] blasted before it is grown up.", "vulgate": "habitatores earum breviata manu contremuerunt et confusi sunt facti sunt sicut faenum agri et gramen pascuae et herba tectorum quae exaruit antequam maturesceret;", "brenton": "I weakened their hands, and they withered; and they became as dry grass on the house-tops, and as grass."}}, {"v": 28, "ref": "37:28", "o": "וְ/שִׁבְתְּ/ךָ֛ וְ/צֵאתְ/ךָ֥ וּ/בוֹאֲ/ךָ֖ יָדָ֑עְתִּי וְ/אֵ֖ת הִֽתְרַגֶּזְ/ךָ֥ אֵלָֽ/י", "en": {"kjv": "But I know thy abode, and thy going out, and thy coming in, and thy rage against me.", "web": "But I know your sitting down, your going out, your coming in, and your raging against me.", "bsb": "But I know your sitting down, your going out and coming in, and your raging against Me.", "asv": "But I know thy sitting down, and thy going out, and thy coming in, and thy raging against me.", "ylt": "And thy sitting down, and thy going out, And thy coming in, I have known, And thy anger towards Me.", "dra": "I know thy dwelling, and thy going out, and thy coming in, and thy rage against me.", "bbe": "But I have knowledge of your getting up and your resting, of your going out and your coming in.", "geneva": "But I know thy dwelling, and thy going out, and thy comming in, and thy fury against me.", "wycliffe": "Y knew thi dwellyng, and thi goyng out, and thin entryng, and thi woodnesse ayens me.", "rotherham": "Howbeit, thine abode and thy coming out and thy going in, I know,—and thy raging against me.", "darby": "But I know thine abode, and thy going out, and thy coming in, and thy raging against me.", "twenty": "", "jps": "But I know thy sitting down, and thy going out, and thy coming in, and thy raging against Me.", "acv": "But I know thy sitting down, and thy going out, and thy coming in, and thy raging against me.", "anderson": "", "haweis": "", "noyes": "I know thy sitting down, thy going out, and thy coming in, And thy rage against me.", "webster": "But I know thy abode, and thy going out, and thy coming in, and thy rage against me.", "vulgate": "habitationem tuam et egressum tuum et introitum tuum cognovi et insaniam tuam contra me;", "brenton": "But now I know thy rest, and thy going out, and thy coming in."}}, {"v": 29, "ref": "37:29", "o": "יַ֚עַן הִתְרַגֶּזְ/ךָ֣ אֵלַ֔/י וְ/שַׁאֲנַנְ/ךָ֖ עָלָ֣ה בְ/אָזְנָ֑/י וְ/שַׂמְתִּ֨י חַחִ֜/י בְּ/אַפֶּ֗/ךָ וּ/מִתְגִּ/י֙ בִּ/שְׂפָתֶ֔י/ךָ וַ/הֲשִׁ֣יבֹתִ֔י/ךָ בַּ/דֶּ֖רֶךְ אֲשֶׁר בָּ֥אתָ בָּֽ/הּ", "en": {"kjv": "Because thy rage against me, and thy tumult, is come up into mine ears, therefore will I put my hook in thy nose, and my bridle in thy lips, and I will turn thee back by the way by which thou camest.", "web": "Because of your raging against me, and because your arrogance has come up into my ears, therefore will I put my hook in your nose and my bridle in your lips, and I will turn you back by the way by which you came.", "bsb": "Because your rage and arrogance against Me have reached My ears, I will put My hook in your nose and My bit in your mouth; I will send you back the way you came.’", "asv": "Because of thy raging against me, and because thine arrogancy is come up into mine ears, therefore will I put my hook in thy nose, and my bridle in thy lips, and I will turn thee back by the way by which thou camest.", "ylt": "Because of thy anger towards Me, And thy noise--it came up into Mine ears, I have put My hook in thy nose, And My bridle in thy lips, And I have caused thee to turn back In the way in which thou camest.", "dra": "When thou wast mad against me, thy pride came up to my ears: therefore I will put a ring in thy nose, and a bit between thy lips, and I will turn thee back by the way by which thou camest.", "bbe": "Because your wrath against me and your pride have come to my ears, I will put my hook in your nose and my cord in your lips, and I will make you go back by the way you came.", "geneva": "Because thou ragest against me, and thy tumult is come vnto mine eares, therefore will I put mine hooke in thy nostrels, and my bridle in thy lips, and wil bring thee backe againe the same way thou camest.", "wycliffe": "Whanne thou were wood ayens me, thi pride stiede in to myn eeris; therfor Y schal sette a ryng in thi nosethirlis, and a bridil in thi lippis; and Y schal lede thee ayen in to the weie, bi which thou camest.", "rotherham": "Because, thy raging against me, and thy contempt, have come up into mine ears, Therefore will I put My ring in thy nose, and My bit in thy lips, And will turn thee back, by the way by which thou camest.", "darby": "Because thy raging against me and thine arrogance is come up into mine ears, I will put my ring in thy nose, and my bridle in thy lips, and I will make thee go back by the way by which thou camest.", "twenty": "", "jps": "Because of thy raging against Me, and for that thine uproar is come up into Mine ears, therefore will I put My hook in thy nose, and My bridle in thy lips, and I will turn thee back by the way by which thou camest.", "acv": "Because of thy raging against me, and because thine arrogance has come up into my ears, therefore I will put my hook in thy nose, and my bridle in thy lips, and I will turn thee back by the way by which thou came.", "anderson": "", "haweis": "", "noyes": "Because thy rage against me, and thy insolence, is come up into my ears, I will put my ring into thy nose, And my bridle into thy lips, And turn thee back by the way in which thou camest.", "webster": "Because thy rage against me, and thy tumult, is come up into my ears, therefore I will put my hook in thy nose, and my bridle in thy lips, and I will turn thee back by the way by which thou camest.", "vulgate": "cum fureres adversum me superbia tua ascendit in aures meas ponam ergo circulum in naribus tuis et frenum in labiis tuis et reducam te in viam per quam venisti;", "brenton": "And thy wrath wherewith thou hast been enraged, and thy rancour has come up to me; therefore I will put a hook in thy nose, and a bit in thy lips, and will turn thee back by the way by which thou camest."}}, {"v": 30, "ref": "37:30", "o": "וְ/זֶה לְּ/ךָ֣ הָ/א֔וֹת אָכ֤וֹל הַ/שָּׁנָה֙ סָפִ֔יחַ וּ/בַ/שָּׁנָ֥ה הַ/שֵּׁנִ֖ית שָׁחִ֑יס וּ/בַ/שָּׁנָ֣ה הַ/שְּׁלִישִׁ֗ית זִרְע֧וּ וְ/קִצְר֛וּ וְ/נִטְע֥וּ כְרָמִ֖ים ו/אכול וְ/אִכְל֥וּ פִרְיָֽ/ם", "en": {"kjv": "And this shall be a sign unto thee, Ye shall eat this year such as groweth of itself; and the second year that which springeth of the same: and in the third year sow ye, and reap, and plant vineyards, and eat the fruit thereof.", "web": "This shall be the sign to you. You will eat this year that which grows of itself, and in the second year that which springs from the same; and in the third year sow and reap and plant vineyards, and eat their fruit.", "bsb": "And this will be a sign to you, O Hezekiah: This year you will eat what grows on its own, and in the second year what springs from the same. But in the third year you will sow and reap; you will plant vineyards and eat their fruit.", "asv": "And this shall be the sign unto thee: ye shall eat this year that which groweth of itself, and in the second year that which springeth of the same; and in the third year sow ye, and reap, and plant vineyards, and eat the fruit thereof.", "ylt": "--And this to thee is the sign, Food of the year is self-sown grain, And in the second year the spontaneous growth, And in the third year, sow ye and reap, And plant vineyards, and eat their fruit.", "dra": "But to thee this shall be a sign: Eat this year the things that spring of themselves, and in the second year eat fruits: but in the third year sow and reap, and plant vineyards, and eat the fruit of them.", "bbe": "And this will be the sign to you: you will get your food this year from what comes up of itself, and in the second year from the produce of the same; and in the third year you will put in your seed, and get in the grain, and make vine-gardens, and take of their fruit.", "geneva": "And this shalbe a signe vnto thee, O Hezekiah, Thou shalt eate this yeere such as groweth of it selfe: and the second yeere, such things as growe without sowing: and in the third yeere, sowe ye and reape, and plant vineyards, and eate the fruite thereof.", "wycliffe": "Forsothe to thee, Ezechie, this schal be a signe; ete thou in this yeer tho thingis that growen bi her fre wille, and in the secunde yeer ete thou applis; but in the thridde yeer sowe ye, and repe ye, and plaunte ye vyneris, and ete ye the fruyt of tho.", "rotherham": "And, this unto thee, is the sign, Eating this year, the growth of scattered seeds, And in the second year, that which shooteth up of itself,—Then in the third year, Sow ye—and reap, and Plant ye vineyards, and eat the fruit thereof.", "darby": "And this [shall be] the sign unto thee: there shall be eaten this year such as groweth of itself; and in the second year that which springeth of the same; but in the third year sow ye, and reap, and plant vineyards and eat the fruit thereof.", "twenty": "", "jps": "And this shall be the sign unto thee: ye shall eat this year that which groweth of itself, and in the second year that which springeth of the same; and in the third year sow ye, and reap, and plant vineyards, and eat the fruit thereof.", "acv": "And this shall be the sign to thee. Ye shall eat this year that which grows of itself, and in the second year that which springs of the same, and in the third year sow ye, and reap, and plant vineyards, and eat the fruit of it.", "anderson": "", "haweis": "", "noyes": "And this shall be the sign to thee; Eat this year that which groweth of itself, And in the second year that which groweth of itself, And in the third year ye shall sow and reap, And plant vineyards, and eat the fruit thereof.", "webster": "And this [shall be] a sign to thee, Ye shall eat [this] year such as groweth of itself; and the second year that which springeth of the same: and in the third year sow ye, and reap, and plant vineyards, and eat the fruit of them.", "vulgate": "tibi autem hoc erit signum comede hoc anno quae sponte nascuntur et in anno secundo pomis vescere in anno autem tertio seminate et metite et plantate vineas et comedite fructum earum;", "brenton": "And this shall be a sign to thee, Eat this year what thou hast sown; and the second year that which is left: and the third year sow, and reap, and plant vineyards, and eat the fruit of them."}}, {"v": 31, "ref": "37:31", "o": "וְ/יָ֨סְפָ֜ה פְּלֵיטַ֧ת בֵּית יְהוּדָ֛ה הַ/נִּשְׁאָרָ֖ה שֹׁ֣רֶשׁ לְ/מָ֑טָּה וְ/עָשָׂ֥ה פְרִ֖י לְ/מָֽעְלָ/ה", "en": {"kjv": "And the remnant that is escaped of the house of Judah shall again take root downward, and bear fruit upward:", "web": "The remnant that is escaped of the house of Judah will again take root downward, and bear fruit upward.", "bsb": "And the surviving remnant of the house of Judah will again take root below and bear fruit above.", "asv": "And the remnant that is escaped of the house of Judah shall again take root downward, and bear fruit upward.", "ylt": "And it hath continued--the escaped Of the house of Judah that hath been left--To take root beneath, And it hath made fruit upward.", "dra": "And that which shall be saved of the house of Juda, and which is left, shall take root downward, and shall bear fruit upward:", "bbe": "And those of Judah who are still living will again take root in the earth, and give fruit.", "geneva": "And the remnant that is escaped of the house of Iudah, shall againe take roote downward and beare fruite vpward.", "wycliffe": "And that that is sauyd of the hous of Juda, and that, that is left, schal sende roote bynethe, and schal make fruyt aboue;", "rotherham": "Then shall the escaped of the house of Judah that remain, again, Take root downward,—And bear fruit upward.", "darby": "And the remnant that is escaped of the house of Judah shall again take root downward, and bear fruit upward;", "twenty": "", "jps": "And the remnant that is escaped of the house of Judah shall again take root downward, and bear fruit upward.", "acv": "And the remnant that is escaped of the house of Judah shall again take root downward, and bear fruit upward.", "anderson": "", "haweis": "", "noyes": "And the remnant of the house of Judah, that have escaped, Shall again strike root downward, And bear fruit upward.", "webster": "And the remnant that hath escaped of the house of Judah shall again take root downward, and bear fruit upward:", "vulgate": "et mittet id quod salvatum fuerit de domo Iuda et quod reliquum est radicem deorsum et faciet fructum sursum;", "brenton": "And they that are left in Judea shall take root downward, and bear fruit upward:"}}, {"v": 32, "ref": "37:32", "o": "כִּ֤י מִ/ירֽוּשָׁלִַ֨ם֙ תֵּצֵ֣א שְׁאֵרִ֔ית וּ/פְלֵיטָ֖ה מֵ/הַ֣ר צִיּ֑וֹן קִנְאַ֛ת יְהוָ֥ה צְבָא֖וֹת תַּֽעֲשֶׂה זֹּֽאת", "en": {"kjv": "For out of Jerusalem shall go forth a remnant, and they that escape out of mount Zion: the zeal of the Lord of hosts shall do this.", "web": "For out of Jerusalem a remnant will go out, and survivors will escape from Mount Zion. The zeal of Yahweh of Armies will perform this.’", "bsb": "For a remnant will go forth from Jerusalem, and survivors from Mount Zion. The zeal of the LORD of Hosts will accomplish this.", "asv": "For out of Jerusalem shall go forth a remnant, and out of mount Zion they that shall escape. The zeal of Jehovah of hosts will perform this.", "ylt": "For from Jerusalem goeth forth a remnant, And an escape from mount Zion, The zeal of Jehovah of Hosts doth this.", "dra": "For out of Jerusalem shall go forth a remnant, and salvation from mount Sion: the zeal of the Lord of hosts shall do this.", "bbe": "For from Jerusalem those who have been kept safe will go out, and those who are still living will go out of Mount Zion: by the fixed purpose of the Lord of armies this will be done.", "geneva": "For out of Ierusalem shall goe a remnant, and they that escape out of mount Zion: the zeale of the Lord of hostes shall doe this.", "wycliffe": "for whi relifs schulen go out of Jerusalem, and saluacioun fro the hil of Sion; the feruent loue of the Lord of oostis schal do this thing.", "rotherham": "For, out of Jerusalem, shall come forth a remnant, And that which hath escaped, out of Mount Zion,—the jealousy of Yahweh of hosts, will perform, this.", "darby": "for out of Jerusalem shall go forth a remnant, and out of mount Zion they that escape: the zeal of Jehovah of hosts shall do this.", "twenty": "", "jps": "For out of Jerusalem shall go forth a remnant, and out of mount Zion they that shall escape; the zeal of HaShem of hosts shall perform this.", "acv": "For out of Jerusalem shall go forth a remnant, and out of mount Zion those who shall escape. The zeal of Jehovah of hosts will perform this.", "anderson": "", "haweis": "", "noyes": "For from Jerusalem shall go forth a remnant, And they that have escaped from mount Zion. The zeal of Jehovah of hosts will perform this.", "webster": "For out of Jerusalem shall go forth a remnant, and they that escape from mount Zion: the zeal of the LORD of hosts will do this.", "vulgate": "quia de Hierusalem exibunt reliquiae et salvatio de monte Sion zelus Domini exercituum faciet istud;", "brenton": "for out of Jerusalem there shall be a remnant, and the saved ones out of mount Sion: the zeal of the Lord of hosts shall perform this."}}, {"v": 33, "ref": "37:33", "o": "לָ/כֵ֗ן כֹּֽה אָמַ֤ר יְהוָה֙ אֶל מֶ֣לֶךְ אַשּׁ֔וּר לֹ֤א יָבוֹא֙ אֶל הָ/עִ֣יר הַ/זֹּ֔את וְ/לֹֽא יוֹרֶ֥ה שָׁ֖ם חֵ֑ץ וְ/לֹֽא יְקַדְּמֶ֣/נָּה מָגֵ֔ן וְ/לֹֽא יִשְׁפֹּ֥ךְ עֳלֶ֖י/הָ סֹלְלָֽה", "en": {"kjv": "Therefore thus saith the Lord concerning the king of Assyria, He shall not come into this city, nor shoot an arrow there, nor come before it with shields, nor cast a bank against it.", "web": "Therefore thus says Yahweh concerning the king of Assyria, ‘He will not come to this city, nor shoot an arrow there, neither will he come before it with shield, nor cast up a mound against it.", "bsb": "So this is what the LORD says about the king of Assyria: ‘He will not enter this city or shoot an arrow into it. He will not come before it with a shield or build up a siege ramp against it.", "asv": "Therefore thus saith Jehovah concerning the king of Assyria, He shall not come unto this city, nor shoot an arrow there, neither shall he come before it with shield, nor cast up a mound against it.", "ylt": "Therefore, thus said Jehovah, Concerning the king of Asshur: He doth not come in unto this city, Nor doth he shoot there an arrow, Nor doth he come before it with shield, Nor doth he pour out against it a mount.", "dra": "Wherefore thus saith the Lord concerning the king of the Assyrians: He shall not come into this city, nor shoot an arrow into it, nor come before it with shield, nor cast a trench about it.", "bbe": "For this cause the Lord says about the king of Assyria, He will not come into this town, or send an arrow against it; he will not come before it with arms, or put up an earthwork against it.", "geneva": "Therefore thus sayth the Lord, concerning the King of Asshur, He shall not enter into this citie, nor shoote an arrow there, nor come before it with shield, nor cast a mount against it.", "wycliffe": "Therfor the Lord seith these thingis of the kyng of Assiriens, He schal not entre in to this citee, and he schal not schete there an arowe; and a scheeld schal not ocupie it, and he schal not sende erthe in the cumpas therof.", "rotherham": "Therefore, thus, saith Yahweh, concerning the king of Assyria, He shall not enter this city, Nor shoot there, an arrow,—Nor attack it with shield, Nor cast up against it a mound:", "darby": "Therefore thus saith Jehovah concerning the king of Assyria: He shall not come into this city, nor shoot an arrow there, nor come before it with shield, nor cast a bank against it.", "twenty": "", "jps": "Therefore thus saith HaShem concerning the king of Assyria: He shall not come unto this city, nor shoot an arrow there, neither shall he come before it with shield, nor cast a mound against it.", "acv": "Therefore thus says Jehovah concerning the king of Assyria, He shall not come to this city, nor shoot an arrow there. Neither shall he come before it with shield, nor cast up a mound against it.", "anderson": "", "haweis": "", "noyes": "Therefore thus saith Jehovah of hosts concerning the king of Assyria; He shall not come into this city, Nor shoot an arrow into it; He shall not present a shield before it, Nor cast up a mound against it.", "webster": "Therefore thus saith the LORD concerning the king of Assyria, He shall not come into this city, nor shoot an arrow there, nor come before it with shields, nor cast a mound against it.", "vulgate": "propterea haec dicit Dominus de rege Assyriorum non introibit civitatem hanc et non iaciet ibi sagittam et non occupabit eam clypeus et non mittet in circuitu eius aggerem;", "brenton": "Therefore thus saith the Lord concerning the king of the Assyrians, He shall not enter into this city, nor cast a weapon against it, nor bring a shield against it, nor make a rampart round it."}}, {"v": 34, "ref": "37:34", "o": "בַּ/דֶּ֥רֶךְ אֲשֶׁר בָּ֖א בָּ֣/הּ יָשׁ֑וּב וְ/אֶל הָ/עִ֥יר הַ/זֹּ֛את לֹ֥א יָב֖וֹא נְאֻם יְהוָֽה", "en": {"kjv": "By the way that he came, by the same shall he return, and shall not come into this city, saith the Lord.", "web": "By the way that he came, by the same he shall return, and he shall not come to this city,’ says Yahweh.", "bsb": "He will go back the way he came, and he will not enter this city,’ declares the LORD.", "asv": "By the way that he came, by the same shall he return, and he shall not come unto this city, saith Jehovah.", "ylt": "In the way that he came, in it he turneth back, And unto this city he doth not come in, An affirmation of Jehovah,", "dra": "By the way that he came, he shall return, and into this city he shall not come, saith the Lord.", "bbe": "By the way he came he will go back, and he will not get into this town.", "geneva": "By the same way that he came, he shall returne, and not come into this citie, saith the Lord.", "wycliffe": "In the weie in which he cam, he schal turne ayen bi it; and he schal not entre in to this citee, seith the Lord.", "rotherham": "By the way that he Came in, By the Same, shall he return,—And into this city, shall he not enter, Declareth Yahweh.", "darby": "By the way that he came, by the same shall he return, and shall not come into this city, saith Jehovah.", "twenty": "", "jps": "By the way that he came, by the same shall he return, and he shall not come unto this city, saith HaShem.", "acv": "By the way that he came, by the same he shall return, and he shall not come to this city, says Jehovah.", "anderson": "", "haweis": "", "noyes": "By the way in which he came, by the same shall he return, And into this city shall he not come, saith Jehovah.", "webster": "By the way that he came, by the same shall he return, and shall not come into this city, saith the LORD.", "vulgate": "in via qua venit per eam revertetur et civitatem hanc non ingredietur dicit Dominus;", "brenton": "But by the way by which he came, by it shall he return, and shall not enter into this city: thus saith the Lord."}}, {"v": 35, "ref": "37:35", "o": "וְ/גַנּוֹתִ֛י עַל הָ/עִ֥יר הַ/זֹּ֖את לְ/הֽוֹשִׁיעָ֑/הּ לְמַֽעֲנִ֔/י וּ/לְמַ֖עַן דָּוִ֥ד עַבְדִּֽ/י", "en": {"kjv": "For I will defend this city to save it for mine own sake, and for my servant David’s sake.", "web": "‘For I will defend this city to save it, for my own sake, and for my servant David’s sake.’”", "bsb": "‘I will defend this city and save it for My own sake and for the sake of My servant David.’”", "asv": "For I will defend this city to save it, for mine own sake, and for my servant David’s sake.", "ylt": "And I have covered over this city, To save it, for Mine own sake, And for the sake of David My servant.'", "dra": "And I will protect this city, and will save it for my own sake, and for the sake of David my servant.", "bbe": "For I will keep this town safe, for my honour, and for the honour of my servant David.", "geneva": "For I will defend this citie to saue it, for mine owne sake, and for my seruant Dauids sake.", "wycliffe": "And Y schal defende this citee, that Y saue it, for me, and for Dauid, my seruaunt.", "rotherham": "Thus will I throw a covering over this city to save it,—For mine own sake, And for the sake of David my servant.", "darby": "And I will defend this city, to save it, for mine own sake, and for my servant David's sake.", "twenty": "", "jps": "For I will defend this city to save it, for Mine own sake, and for My servant David's sake.'", "acv": "For I will defend this city to save it, for my own sake, and for my servant David's sake.", "anderson": "", "haweis": "", "noyes": "For I will defend this city, and deliver it, For mine own sake, and for my servant David’s sake.", "webster": "For I will defend this city, to save it for my own sake, and for my servant David's sake.", "vulgate": "et protegam civitatem istam ut salvem eam propter me et propter David servum meum;", "brenton": "I will protect this city to save it for my own sake, and for my servant David's sake."}}, {"v": 36, "ref": "37:36", "o": "וַ/יֵּצֵ֣א מַלְאַ֣ךְ יְהוָ֗ה וַ/יַּכֶּה֙ בְּ/מַחֲנֵ֣ה אַשּׁ֔וּר מֵאָ֛ה וּ/שְׁמֹנִ֥ים וַ/חֲמִשָּׁ֖ה אָ֑לֶף וַ/יַּשְׁכִּ֣ימוּ בַ/בֹּ֔קֶר וְ/הִנֵּ֥ה כֻלָּ֖/ם פְּגָרִ֥ים מֵתִֽים", "en": {"kjv": "Then the angel of the Lord went forth, and smote in the camp of the Assyrians a hundred and fourscore and five thousand: and when they arose early in the morning, behold, they were all dead corpses.", "web": "Yahweh’s angel went out and struck one hundred and eighty-five thousand men in the camp of the Assyrians. When men arose early in the morning, behold, these were all dead bodies.", "bsb": "Then the angel of the LORD went out and struck down 185,000 men in the camp of the Assyrians. When the people got up the next morning, there were all the dead bodies!", "asv": "And the angel of Jehovah went forth, and smote in the camp of the Assyrians a hundred and fourscore and five thousand; and when men arose early in the morning, behold, these were all dead bodies.", "ylt": "And a messenger of Jehovah goeth out, and smiteth in the camp of Asshur a hundred and eighty and five thousand; and men rise early in the morning, and lo, all of them are dead corpses.", "dra": "And the angel of the Lord went out and slew in the camp of the Assyrians a hundred and eighty-five thousand. And they arose in the morning, and behold they were all dead corpses.", "bbe": "And the angel of the Lord went out and put to death in the army of the Assyrians a hundred and eighty-five thousand men: and when the people got up early in the morning, there was nothing to be seen but dead bodies.", "geneva": "Then the Angel of the Lord went out, and smote in the campe of Asshur an hundreth, fourescore, and fiue thousand: so when they arose early in the morning, beholde, they were all dead corpses.", "wycliffe": "Forsothe the aungel of the Lord yede out, and killide an hundride thousynde and fourscoor and fyue thousynde in the tentis of Assiriens; and thei risen eerli, and lo! alle men weren careyns of deed men.", "rotherham": "Then went forth the messenger of Yahweh, and smote—in the camp of the Assyrians—a hundred and eighty-five thousand,—and when men arose early in the morning, lo! they were all, dead bodies!", "darby": "And an angel of Jehovah went forth, and smote in the camp of the Assyrians a hundred and eighty-five thousand. And when they arose early in the morning, behold, they were all dead bodies.", "twenty": "", "jps": "And the angel of HaShem went forth, and smote in the camp of the Assyrians a hundred and fourscore and five thousand; and when men arose early in the morning, behold, they were all dead corpses.", "acv": "And the agent of Jehovah went forth, and smote in the camp of the Assyrians a hundred and eighty-five thousand. And when men arose early in the morning, behold, these were all dead bodies.", "anderson": "", "haweis": "", "noyes": "Then an angel of Jehovah went forth, and smote in the camp of the Assyrians a hundred and eighty-five thousand men; and when the people arose early in the morning, behold they were all dead corpses.", "webster": "Then the angel of the LORD went forth, and smote in the camp of the Assyrians a hundred and eighty five thousand: and when they arose early in the morning, behold, they [were] all dead corpses.", "vulgate": "egressus est autem angelus Domini et percussit in castris Assyriorum centum octoginta quinque milia et surrexerunt mane et ecce omnes cadavera mortuorum;", "brenton": "And the angel of the Lord went forth, and slew out of the camp of the Assyrians a hundred and eighty-five thousand: and they arose in the morning and found all these bodies dead."}}, {"v": 37, "ref": "37:37", "o": "וַ/יִּסַּ֣ע וַ/יֵּ֔לֶךְ וַ/יָּ֖שָׁב סַנְחֵרִ֣יב מֶֽלֶךְ אַשּׁ֑וּר וַ/יֵּ֖שֶׁב בְּ/נִֽינְוֵֽה", "en": {"kjv": "So Sennacherib king of Assyria departed, and went and returned, and dwelt at Nineveh.", "web": "So Sennacherib king of Assyria departed, went away, returned to Nineveh, and stayed there.", "bsb": "So Sennacherib king of Assyria broke camp and withdrew. He returned to Nineveh and stayed there.", "asv": "So Sennacherib king of Assyria departed, and went and returned, and dwelt at Nineveh.", "ylt": "And journey, and go, and turn back doth Sennacherib king of Asshur, and dwelleth in Nineveh.", "dra": "And Sennacherib the king of the Assyrians went out and departed, and returned, and dwelt in Ninive.", "bbe": "Sennacherib, king of Assyria, went back to his place at Nineveh.", "geneva": "So Saneherib king of Asshur departed, and went away and returned and dwelt at Nineueh.", "wycliffe": "And Sennacherib yede out of Jude, and wente awei. And Sennacherib, the kyng of Assiriens, turnede ayen, and dwellide in Nynyue.", "rotherham": "So Sennacherib the king of Assyria brake up, and went his way, and returned,—and remained in Nineveh.", "darby": "And Sennacherib king of Assyria departed, and went and returned, and abode at Nineveh.", "twenty": "", "jps": "So Sennacherib king of Assyria departed, and went, and returned, and dwelt at Nineveh.", "acv": "So Sennacherib king of Assyria departed, and went and returned, and dwelt at Nineveh.", "anderson": "", "haweis": "", "noyes": "Then Sennacherib, king of Assyria, decamped, and went away, and returned, and dwelt at Nineveh.", "webster": "So Sennacherib king of Assyria departed, and went and returned, and dwelt at Nineveh.", "vulgate": "et egressus est et abiit et reversus est Sennacherib rex Assyriorum et habitavit in Nineve;", "brenton": "And Sennacherim king of the Assyrians turned and departed, and dwelt in Nineve."}}, {"v": 38, "ref": "37:38", "o": "וַ/יְהִי֩ ה֨וּא מִֽשְׁתַּחֲוֶ֜ה בֵּ֣ית נִסְרֹ֣ךְ אֱלֹהָ֗י/ו וְֽ/אַדְרַמֶּ֨לֶךְ וְ/שַׂרְאֶ֤צֶר בָּנָי/ו֙ הִכֻּ֣/הוּ בַ/חֶ֔רֶב וְ/הֵ֥מָּה נִמְלְט֖וּ אֶ֣רֶץ אֲרָרָ֑ט וַ/יִּמְלֹ֛ךְ אֵֽסַר חַדֹּ֥ן בְּנ֖/וֹ תַּחְתָּֽי/ו", "en": {"kjv": "And it came to pass, as he was worshipping in the house of Nisroch his god, that Adrammelech and Sharezer his sons smote him with the sword; and they escaped into the land of Armenia: and Esar–haddon his son reigned in his stead.", "web": "As he was worshiping in the house of Nisroch his god, Adrammelech and Sharezer his sons struck him with the sword; and they escaped into the land of Ararat. Esar Haddon his son reigned in his place.", "bsb": "One day, while he was worshiping in the temple of his god Nisroch, his sons Adrammelech and Sharezer put him to the sword and escaped to the land of Ararat. And his son Esar-haddon reigned in his place.", "asv": "And it came to pass, as he was worshipping in the house of Nisroch his god, that Adrammelech and Sharezer his sons smote him with the sword; and they escaped into the land of Ararat. And Esar-haddon his son reigned in his stead.", "ylt": "And it cometh to pass, he is bowing himself in the house of Nisroch his god, and Adrammelech and Sharezer his sons have smitten him with the sword, and they have escaped to the land of Ararat, and Esar-Haddon his son reigneth in his stead.", "dra": "And it came to pass, as he was worshipping in the temple of Nesroch his god, that Adramelech and Sarasar his sons slew him with the sword: and they fled into the land of Ararat, and Asarhaddon his son reigned in his stead.", "bbe": "And it came about, when he was worshipping in the house of Nisroch his god, that his sons Adrammelech and Sharezer put him to death with the sword, and they went in flight into the land of Ararat. And Esar-haddon, his son, became king in his place.", "geneva": "And as he was in the temple worshipping of Nisroch his god, Adramelech and Sharezer his sonnes slewe him with the sword, and they escaped into the land of Ararat: and Esarhaddon his sonne reigned in his steade.", "wycliffe": "And it was don, whanne he worschipide Mesrach, his god, in the temple, Aramalech and Sarasar, hise sones, killiden hym with swerd, and fledden in to the lond of Ararath; and Asaradon, his sone, regnyde for hym.", "rotherham": "And it came to pass, as he was bowing down in the house of Nisroch his god, that, Adrammelech and Sharezer his sons, smote him with the sword, howbeit, they, escaped into the land of Ararat,—and, Esarhaddon his son, reigned, in his stead.", "darby": "And it came to pass, as he was worshipping in the house of Nisroch hisgod, that Adrammelech and Sharezer his sons smote him with the sword; and they escaped into the land of Ararat. And Esarhaddon his son reigned in his stead.", "twenty": "", "jps": "And it came to pass, as he was worshipping in the house of Nisroch his god, that Adrammelech and Sarezer his sons smote him with the sword; and they escaped into the land of Ararat. And Esarhaddon his son reigned in his stead.", "acv": "And it came to pass, as he was worshiping in the house of Nisroch his god, that Adrammelech and Sharezer his sons smote him with the sword, and they escaped into the land of Ararat. And Esar-haddon his son reigned in his stead.", "anderson": "", "haweis": "", "noyes": "And as he was worshipping in the temple of Nisroch, his god, he was slain with the sword by his sons Adrammelech and Sharezer, who escaped into the land of Ararat. And Esarhaddon, his son, reigned in his stead.", "webster": "And it came to pass, as he was worshiping in the house of Nisroch his god, that Adrammelech and Sharezer his sons smote him with the sword; and they escaped into the land of Armenia: and Esar-haddon his son reigned in his stead.", "vulgate": "et factum est cum adoraret in templo Nesrach deum suum Adramelech et Sarasar filii eius percusserunt eum gladio fugeruntque in terram Ararat et regnavit Asoraddon filius eius pro eo;", "brenton": "And while he was worshipping Nasarach his country's god in the house, Adramelech and Sarasar his sons smote him with swords; and they escaped into Armenia: and Asordan his son reigned in his stead."}}]}, {"c": 38, "verses": [{"v": 1, "ref": "38:1", "o": "בַּ/יָּמִ֣ים הָ/הֵ֔ם חָלָ֥ה חִזְקִיָּ֖הוּ לָ/מ֑וּת וַ/יָּב֣וֹא אֵ֠לָי/ו יְשַׁעְיָ֨הוּ בֶן אָמ֜וֹץ הַ/נָּבִ֗יא וַ/יֹּ֨אמֶר אֵלָ֜י/ו כֹּֽה אָמַ֤ר יְהוָה֙ צַ֣ו לְ/בֵיתֶ֔/ךָ כִּ֛י מֵ֥ת אַתָּ֖ה וְ/לֹ֥א תִֽחְיֶֽה", "en": {"kjv": "In those days was Hezekiah sick unto death. And Isaiah the prophet the son of Amoz came unto him, and said unto him, Thus saith the Lord, Set thine house in order: for thou shalt die, and not live.", "web": "In those days was Hezekiah sick and near death. Isaiah the prophet, the son of Amoz, came to him, and said to him, “Thus says Yahweh, ‘Set your house in order, for you will die, and not live.’”", "bsb": "In those days Hezekiah became mortally ill. The prophet Isaiah son of Amoz came to him and said, “This is what the LORD says: ‘Put your house in order, for you are about to die; you will not recover.’”", "asv": "In those days was Hezekiah sick unto death. And Isaiah the prophet the son of Amoz came to him, and said unto him, Thus saith Jehovah, Set thy house in order; for thou shalt die, and not live.", "ylt": "In those days hath Hezekiah been sick unto death, and come in unto him doth Isaiah son of Amoz, the prophet, and saith unto him, `Thus said Jehovah: Give a charge to thy house, for thou art dying, and dost not live.'", "dra": "In those days Ezechias was sick even to death, and Isaiah the son of Amos the prophet cane unto him, and said to him: Thus saith the Lord: Take order with thy house, for thou shalt die, and not live.", "bbe": "In those days Hezekiah was ill and near death. And Isaiah the prophet, the son of Amoz, came to him, and said to him, The Lord says, Put your house in order; for your death is near.", "geneva": "About that time was Hezekiah sicke vnto the death, and the Prophet Isaiah sonne of Amoz came vnto him, and sayd vnto him, Thus sayth the Lord, Put thine house in an order, for thou shalt dye, and not liue.", "wycliffe": "In tho daies Esechie was sijk `til to the deth; and Isaie, the profete, the sone of Amos, entride to hym, and seide to hym, The Lord seith these thingis, Dispose thi hous, for thou schalt die, and thou schalt not lyue.", "rotherham": "In those days, was Hezekiah sick, unto death,—and Isaiah the prophet son of Amoz came in unto him, and said unto him—Thus, saith Yahweh, Set in order thy house, for, about to die thou art and shalt not recover.", "darby": "In those days Hezekiah was sick unto death. And the prophet Isaiah the son of Amoz came to him, and said to him, Thus saith Jehovah: Set thy house in order; for thou shalt die, and not live.", "twenty": "", "jps": "In those days was Hezekiah sick unto death. And Isaiah the prophet the son of Amoz came to him, and said unto him: 'Thus saith HaShem: Set thy house in order; for thou shalt die, and not live.'", "acv": "In those days Hezekiah was sick to death. And Isaiah the prophet the son of Amoz came to him, and said to him, Thus says Jehovah, Set thy house in order, for thou shall die, and not live.", "anderson": "", "haweis": "", "noyes": "In those days was Hezekiah sick unto death; and Isaiah the prophet, the son of Amoz, came to him, and said to him, Set thy house in order, for thou shalt die, and not live.", "webster": "In those days was Hezekiah sick with a mortal disease. And Isaiah the prophet the son of Amoz came to him, and said to him, Thus saith the LORD, Set thy house in order: for thou shalt die, and not live.", "vulgate": "in diebus illis aegrotavit Ezechias usque ad mortem et introivit ad eum Isaias filius Amos propheta et dixit ei haec dicit Dominus dispone domui tuae quia morieris tu et non vives;", "brenton": "And it came to pass at that time, that Ezekias was sick even to death. And Esaias the prophet the son of Amos came to him, and said to him, Thus saith the Lord, Give orders concerning thy house: for thou shalt die, and not live."}}, {"v": 2, "ref": "38:2", "o": "וַ/יַּסֵּ֧ב חִזְקִיָּ֛הוּ פָּנָ֖י/ו אֶל הַ/קִּ֑יר וַ/יִּתְפַּלֵּ֖ל אֶל יְהוָֽה", "en": {"kjv": "Then Hezekiah turned his face toward the wall, and prayed unto the Lord,", "web": "Then Hezekiah turned his face to the wall and prayed to Yahweh,", "bsb": "Then Hezekiah turned his face to the wall and prayed to the LORD,", "asv": "Then Hezekiah turned his face to the wall, and prayed unto Jehovah,", "ylt": "And Hezekiah turneth round his face unto the wall, and prayeth unto Jehovah,", "dra": "And Ezechias turned his face toward the wall, and prayed to the Lord,", "bbe": "And Hezekiah, turning his face to the wall, made his prayer to the Lord, saying,", "geneva": "Then Hezekiah turned his face to the wall, and prayed to the Lord,", "wycliffe": "And Esechie turnede his face to the wal, and preiede the Lord, and seide, Lord, Y biseche;", "rotherham": "Then Hezekiah turned his face unto the wall,—and prayed unto Yahweh;", "darby": "And Hezekiah turned his face to the wall, and prayed to Jehovah,", "twenty": "", "jps": "Then Hezekiah turned his face to the wall, and prayed unto HaShem,", "acv": "Then Hezekiah turned his face to the wall, and prayed to Jehovah,", "anderson": "", "haweis": "", "noyes": "Then Hezekiah turned his face toward the wall, and made his supplication to Jehovah.", "webster": "Then Hezekiah turned his face towards the wall, and prayed to the LORD,", "vulgate": "et convertit Ezechias faciem suam ad parietem et oravit ad Dominum;", "brenton": "And Ezekias turned his face to the wall, and prayed to the Lord, saying,"}}, {"v": 3, "ref": "38:3", "o": "וַ/יֹּאמַ֗ר אָנָּ֤ה יְהוָה֙ זְכָר נָ֞א אֵ֣ת אֲשֶׁ֧ר הִתְהַלַּ֣כְתִּי לְ/פָנֶ֗י/ךָ בֶּֽ/אֱמֶת֙ וּ/בְ/לֵ֣ב שָׁלֵ֔ם וְ/הַ/טּ֥וֹב בְּ/עֵינֶ֖י/ךָ עָשִׂ֑יתִי וַ/יֵּ֥בְךְּ חִזְקִיָּ֖הוּ בְּכִ֥י גָדֽוֹל", "en": {"kjv": "And said, Remember now, O Lord, I beseech thee, how I have walked before thee in truth and with a perfect heart, and have done that which is good in thy sight. And Hezekiah wept sore.", "web": "and said, “Remember now, Yahweh, I beg you, how I have walked before you in truth and with a perfect heart, and have done that which is good in your sight.” Hezekiah wept bitterly.", "bsb": "saying, “Please, O LORD, remember how I have walked before You faithfully and with wholehearted devotion; I have done what was good in Your sight.” And Hezekiah wept bitterly.", "asv": "and said, Remember now, O Jehovah, I beseech thee, how I have walked before thee in truth and with a perfect heart, and have done that which is good in thy sight. And Hezekiah wept sore.", "ylt": "and saith, `I pray thee, O Jehovah, remember, I pray Thee, how I have walked habitually before Thee in truth, and with a perfect heart, and that which is good in thine eyes I have done;' and Hezekiah weepeth--a great weeping.", "dra": "And said: I beseech thee, O Lord, remember how I have walked before thee in truth, and with a perfect heart, and have done that which is good in thy sight. And Ezechias wept with great weeping.", "bbe": "O Lord, keep in mind how I have been true to you with all my heart, and have done what is good in your eyes. And Hezekiah gave way to bitter weeping.", "geneva": "And saide, I beseeche thee, Lord, remember nowe howe I haue walked before thee in trueth, and with a perfite heart, and haue done that which is good in thy sight: and Hezekiah wept sore.", "wycliffe": "haue thou mynde, Y biseche, hou Y yede bifore thee in treuthe, and in perfit herte, and Y dide that that was good bifore thin iyen. And Ezechye wept with greet wepyng.", "rotherham": "and said,—I beseech thee, O Yahweh, remember, I pray thee, how I have walked before thee in faithfulness and with an undivided heart, and, that which is good in thine eyes, have I done. And Hezekiah wept aloud.", "darby": "and said, Ah, Jehovah, remember, I beseech thee, how I have walked before thee in truth and with a perfect heart, and have done that which is good in thy sight. And Hezekiah wept much.", "twenty": "", "jps": "and said: 'Remember now, O HaShem, I beseech Thee, how I have walked before Thee in truth and with a whole heart, and have done that which is good in Thy sight.' And Hezekiah wept sore.", "acv": "and said, Remember now, O Jehovah, I beseech thee, how I have walked before thee in truth and with a perfect heart, and have done that which is good in thy sight. And Hezekiah wept greatly.", "anderson": "", "haweis": "", "noyes": "And he said, I beseech thee, O Jehovah, remember now how I have walked before thee in truth, and with a perfect heart, and have done that which is good in thine eyes! And Hezekiah wept bitterly.", "webster": "And said, Remember now, O LORD, I beseech thee, how I have walked before thee in truth and with a perfect heart, and have done [that which is] good in thy sight. And Hezekiah wept bitterly.", "vulgate": "et dixit obsecro Domine memento quaeso quomodo ambulaverim coram te in veritate et in corde perfecto et quod bonum est in oculis tuis fecerim et flevit Ezechias fletu magno;", "brenton": "Remember, O Lord, how I have walked before thee in truth, with a true heart, and have done that which was pleasing in thy sight. And Ezekias wept bitterly."}}, {"v": 4, "ref": "38:4", "o": "וַֽ/יְהִי֙ דְּבַר יְהוָ֔ה אֶֽל יְשַׁעְיָ֖הוּ לֵ/אמֹֽר", "en": {"kjv": "Then came the word of the Lord to Isaiah, saying,", "web": "Then Yahweh’s word came to Isaiah, saying,", "bsb": "And the word of the LORD came to Isaiah, saying,", "asv": "Then came the word of Jehovah to Isaiah, saying,", "ylt": "And a word of Jehovah is unto Isaiah, saying,", "dra": "And the word of the Lord came to Isaiah, saying:", "bbe": "Then the word of the Lord came to Isaiah, saying,", "geneva": "Then came the worde of the Lord to Isaiah, saying,", "wycliffe": "And the word of the Lord was maad to Isaie, and seide,", "rotherham": "Then came the word of Yahweh unto, Isaiah, saying:", "darby": "And the word of Jehovah came to Isaiah, saying,", "twenty": "", "jps": "Then came the word of HaShem to Isaiah, saying:", "acv": "Then the word of Jehovah came to Isaiah, saying,", "anderson": "", "haweis": "", "noyes": "Then came the word of Jehovah to Isaiah,", "webster": "Then came the word of the LORD to Isaiah, saying,", "vulgate": "et factum est verbum Domini ad Isaiam dicens;", "brenton": "And the word of the Lord came to Esaias, saying, Go, and say to Ezekias,"}}, {"v": 5, "ref": "38:5", "o": "הָל֞וֹךְ וְ/אָמַרְתָּ֣ אֶל חִזְקִיָּ֗הוּ כֹּֽה אָמַ֤ר יְהוָה֙ אֱלֹהֵי֙ דָּוִ֣ד אָבִ֔י/ךָ שָׁמַ֨עְתִּי֙ אֶת תְּפִלָּתֶ֔/ךָ רָאִ֖יתִי אֶת דִּמְעָתֶ֑/ךָ הִנְ/נִי֙ יוֹסִ֣ף עַל יָמֶ֔י/ךָ חֲמֵ֥שׁ עֶשְׂרֵ֖ה שָׁנָֽה", "en": {"kjv": "Go, and say to Hezekiah, Thus saith the Lord, the God of David thy father, I have heard thy prayer, I have seen thy tears: behold, I will add unto thy days fifteen years.", "web": "“Go, and tell Hezekiah, ‘Thus says Yahweh, the God of David your father, “I have heard your prayer. I have seen your tears. Behold, I will add fifteen years to your life.", "bsb": "“Go and tell Hezekiah that this is what the LORD, the God of your father David, says: ‘I have heard your prayer; I have seen your tears. Behold, I will add fifteen years to your life.", "asv": "Go, and say to Hezekiah, Thus saith Jehovah, the God of David thy father, I have heard thy prayer, I have seen thy tears: behold, I will add unto thy days fifteen years.", "ylt": "Go, and thou hast said to Hezekiah, Thus said Jehovah, God of David thy father, `I have heard thy prayer, I have seen thy tear, lo, I am adding to thy days fifteen years,", "dra": "Go and say to Ezechias: Thus saith the Lord the God of David thy father: I have heard thy prayer, and I have seen thy tears: behold I will add to thy days fifteen years:", "bbe": "Go to Hezekiah, and say, The Lord, the God of David, your father, says, Your prayer has come to my ears, and I have seen your weeping: see, I will give you fifteen more years of life.", "geneva": "Goe, and say vnto Hezekiah, Thus saith the Lord God of Dauid thy father, I haue heard thy prayer, and seene thy teares: behold, I will adde vnto thy dayes fifteene yeeres.", "wycliffe": "Go thou, and seie to Ezechye, The Lord God of Dauid, thi fadir, seith these thingis, I haue herd thi preier, and Y siy thi teeris. Lo! Y schal adde on thi daies fiftene yeer;", "rotherham": "Go, and say unto Hezekiah—Thus, saith Yahweh, the God of David thy father: I have heard thy prayer, I have seen thy tears,—Behold me! about to add unto thy days, fifteen years;", "darby": "Go and say to Hezekiah, Thus saith Jehovah, theGod of David thy father: I have heard thy prayer, I have seen thy tears: behold, I will add to thy days fifteen years.", "twenty": "", "jps": "'Go, and say to Hezekiah: Thus saith HaShem, the G-d of David thy father: I have heard thy prayer, I have seen thy tears; behold, I will add unto thy days fifteen years.", "acv": "Go, and say to Hezekiah, Thus says Jehovah, the God of David thy father. I have heard thy prayer. I have seen thy tears. Behold, I will add to thy days fifteen years.", "anderson": "", "haweis": "", "noyes": "Go in and say to Hezekiah, Thus saith Jehovah, the God of David thy father: I have heard thy prayer; I have seen thy tears. Behold, I will add to thy life fifteen years.", "webster": "Go and say to Hezekiah, Thus saith the LORD, the God of David thy father, I have heard thy prayer, I have seen thy tears: behold, I will add to thy days fifteen years.", "vulgate": "vade et dic Ezechiae haec dicit Dominus Deus David patris tui audivi orationem tuam vidi lacrimam tuam ecce ego adiciam super dies tuos quindecim annos;", "brenton": "Thus saith the Lord, the God of David thy father, I have heard thy prayer, and seen thy tears: behold, I will add to thy time fifteen years."}}, {"v": 6, "ref": "38:6", "o": "וּ/מִ/כַּ֤ף מֶֽלֶךְ אַשּׁוּר֙ אַצִּ֣ילְ/ךָ֔ וְ/אֵ֖ת הָ/עִ֣יר הַ/זֹּ֑את וְ/גַנּוֹתִ֖י עַל הָ/עִ֥יר הַ/זֹּֽאת", "en": {"kjv": "And I will deliver thee and this city out of the hand of the king of Assyria: and I will defend this city.", "web": "I will deliver you and this city out of the hand of the king of Assyria, and I will defend this city.", "bsb": "And I will deliver you and this city from the hand of the king of Assyria. I will defend this city.", "asv": "And I will deliver thee and this city out of the hand of the king of Assyria; and I will defend this city.", "ylt": "and out of the hand of the king of Asshur I deliver thee and this city, and have covered over this city.", "dra": "And I will deliver thee and this city out of the hand of the king of the Assyrians, and I will protect it.", "bbe": "And I will keep you and this town safe from the hands of the king of Assyria: and I will keep watch over this town.", "geneva": "And I will deliuer thee out of the hand of the King of Asshur, and this citie: for I will defende this citie.", "wycliffe": "and Y schal delyuere thee and this citee fro the hond of the kyng of Assiriens, and Y schal defende it.", "rotherham": "And out of the hand of the king of Assyria, will I deliver thee, and this city; And I will throw a covering over this city.", "darby": "And I will deliver thee and this city out of the hand of the king of Assyria, and I will defend this city.", "twenty": "", "jps": "And I will deliver thee and this city out of the hand of the king of Assyria; and I will defend this city.", "acv": "And I will deliver thee and this city out of the hand of the king of Assyria, and I will defend this city.", "anderson": "", "haweis": "", "noyes": "And I will deliver thee and this city from the hand of the king of Assyria, and I will defend this city.", "webster": "And I will deliver thee and this city from the hand of the king of Assyria: and I will defend this city.", "vulgate": "et de manu regis Assyriorum eruam te et civitatem istam et protegam eam;", "brenton": "And I will deliver thee and this city out of the hand of the king of the Assyrians: and I will defend this city."}}, {"v": 7, "ref": "38:7", "o": "וְ/זֶה לְּ/ךָ֥ הָ/א֖וֹת מֵ/אֵ֣ת יְהוָ֑ה אֲשֶׁר֙ יַעֲשֶׂ֣ה יְהוָ֔ה אֶת הַ/דָּבָ֥ר הַ/זֶּ֖ה אֲשֶׁ֥ר דִּבֵּֽר", "en": {"kjv": "And this shall be a sign unto thee from the Lord, that the Lord will do this thing that he hath spoken;", "web": "This shall be the sign to you from Yahweh, that Yahweh will do this thing that he has spoken.", "bsb": "This will be a sign to you from the LORD that He will do what He has promised:", "asv": "And this shall be the sign unto thee from Jehovah, that Jehovah will do this thing that he hath spoken:", "ylt": "And this is to thee the sign from Jehovah, that Jehovah doth this thing that He hath spoken.", "dra": "And this shall be a sign to thee from the Lord, that the Lord will do this word which he hath spoken:", "bbe": "And Isaiah said, This is the sign the Lord will give you, that he will do what he has said:", "geneva": "And this signe shalt thou haue of ye Lord, that ye Lord will do this thing that he hath spoken,", "wycliffe": "Forsothe this schal be to thee a signe of the Lord, that the Lord schal do this word, which he spak.", "rotherham": "And, this, to thee, shall be the sign from Yahweh,—that Yahweh will do this thing which he hath spoken:—", "darby": "And this [shall be] the sign to thee from Jehovah, that Jehovah will do this thing that he hath spoken:", "twenty": "", "jps": "And this shall be the sign unto thee from HaShem, that HaShem will do this thing that He hath spoken:", "acv": "And this shall be the sign to thee from Jehovah, that Jehovah will do this thing that he has spoken:", "anderson": "", "haweis": "", "noyes": "And this shall be the sign to thee from Jehovah, that Jehovah will do that which he hath spoken.", "webster": "And this [shall be] a sign to thee from the LORD, that the LORD will do this thing that he hath spoken;", "vulgate": "hoc autem tibi erit signum a Domino quia faciet Dominus verbum hoc quod locutus est;", "brenton": "And this shall be a sign to thee from the Lord, that God will do this thing;"}}, {"v": 8, "ref": "38:8", "o": "הִנְ/נִ֣י מֵשִׁ֣יב אֶת צֵ֣ל הַֽ/מַּעֲל֡וֹת אֲשֶׁ֣ר יָרְדָה֩ בְ/מַעֲל֨וֹת אָחָ֥ז בַּ/שֶּׁ֛מֶשׁ אֲחֹרַנִּ֖ית עֶ֣שֶׂר מַעֲל֑וֹת וַ/תָּ֤שָׁב הַ/שֶּׁ֨מֶשׁ֙ עֶ֣שֶׂר מַעֲל֔וֹת בַּֽ/מַּעֲל֖וֹת אֲשֶׁ֥ר יָרָֽדָה", "en": {"kjv": "Behold, I will bring again the shadow of the degrees, which is gone down in the sun dial of Ahaz, ten degrees backward. So the sun returned ten degrees, by which degrees it was gone down.", "web": "Behold, I will cause the shadow on the sundial, which has gone down on the sundial of Ahaz with the sun, to return backward ten steps. So the sun returned ten steps on the sundial on which it had gone down.”’”", "bsb": "I will make the sun’s shadow that falls on the stairway of Ahaz go back ten steps.’” So the sunlight went back the ten steps it had descended.", "asv": "behold, I will cause the shadow on the steps, which is gone down on the dial of Ahaz with the sun, to return backward ten steps. So the sun returned ten steps on the dial whereon it was gone down.", "ylt": "Lo, I am bringing back the shadow of the degrees that it hath gone down on the degrees of Ahaz, by the sun, backward ten degrees:' and the sun turneth back ten degrees in the degrees that it had gone down.", "dra": "Behold I will bring again the shadow of the lines, by which it is now gone down in the sun dial of Achaz with the sun, ten lines backward. And the sun returned ten lines by the degrees by which it was gone down.", "bbe": "See, I will make the shade which has gone down on the steps of Ahaz with the sun, go back ten steps. So the shade went back the ten steps by which it had gone down.", "geneva": "Beholde, I will bring againe the shadowe of the degrees (whereby it is gone downe in the diall of Ahaz by the sunne) ten degrees backeward: so the sunne returned by tenne degrees, by the which degrees it was gone downe.", "wycliffe": "Lo! Y schal make the schadewe of lynes, bi which it yede doun in the orologie of Achas, in the sunne, to turne ayen backward bi ten lynes. And the sunne turnede ayen bi ten lynes, bi degrees bi whiche it hadde go doun.", "rotherham": "Behold me! causing the shadow on the steps, which hath come gone down on the steps of Ahaz with the sun, to return, backwards ten steps. So the sun returned ten steps, by the steps which it had come down.", "darby": "behold, I will bring again the shadow of the degrees which hath gone down with the sun on the dial of Ahaz, ten degrees backward. So the sun returned on the dial ten degrees, by which it had gone down.", "twenty": "", "jps": "behold, I will cause the shadow of the dial, which is gone down on the sun-dial of Ahaz, to return backward ten degrees.' So the sun returned ten degrees, by which degrees it was gone down.", "acv": "Behold, I will cause the shadow on the steps, which has gone down on the dial of Ahaz with the sun, to return backward ten steps. So the sun returned ten steps on the dial on which it had gone down.", "anderson": "", "haweis": "", "noyes": "Behold, I will cause the shadow upon the dial, which hath gone down upon the dial of Ahaz with the sun, to go back ten degrees. So the sun went back ten degrees, which degrees it had gone down.", "webster": "Behold, I will bring again the shadow of the degrees, which hath gone down on the sun-dial of Ahaz ten degrees backward. So the sun returned ten degrees, by which degrees it had gone down.", "vulgate": "ecce ego reverti faciam umbram linearum per quas descenderat in horologio Ahaz in sole retrorsum decem lineis et reversus est sol decem lineis per gradus quos descenderat;", "brenton": "behold, I will turn back the shadow of the degrees of the dial by which ten degrees on the house of thy father the sun has gone down—I will turn back the sun the ten degrees; so the sun went back the ten degrees by which the shadow had gone down."}}, {"v": 9, "ref": "38:9", "o": "מִכְתָּ֖ב לְ/חִזְקִיָּ֣הוּ מֶֽלֶךְ יְהוּדָ֑ה בַּ/חֲלֹת֕/וֹ וַ/יְחִ֖י מֵ/חָלְיֽ/וֹ", "en": {"kjv": "The writing of Hezekiah king of Judah, when he had been sick, and was recovered of his sickness:", "web": "The writing of Hezekiah king of Judah, when he had been sick, and had recovered of his sickness.", "bsb": "This is a writing by Hezekiah king of Judah after his illness and recovery:", "asv": "The writing of Hezekiah king of Judah, when he had been sick, and was recovered of his sickness.", "ylt": "A writing of Hezekiah king of Judah concerning his being sick, when he reviveth from his sickness:", "dra": "The writing of Ezechias king of Juda, when he had been sick, and was recovered of his sickness.", "bbe": "The writing of Hezekiah, king of Judah, after he had been ill, and had got better from his disease.", "geneva": "The writing of Hezekiah King of Iudah, when he had bene sicke, and was recouered of his sickenesse.", "wycliffe": "The scripture of Ezechie, kyng of Juda, whanne he hadde be sijk, and hadde rekyuered of his sikenesse.", "rotherham": "the writing of Hezekiah king of Judah, when he had been sick and then recovered from his sickness:", "darby": "The writing of Hezekiah king of Judah, when he had been sick and had recovered from his sickness:", "twenty": "", "jps": "The writing of Hezekiah king of Judah, when he had been sick, and was recovered of his sickness.", "acv": "The writing of Hezekiah king of Judah when he had been sick, and was recovered of his sickness:", "anderson": "", "haweis": "", "noyes": "The writing of Hezekiah, king of Judah, when he had been sick, and had recovered from his sickness.", "webster": "The writing of Hezekiah king of Judah, when he had been sick, and had recovered from his sickness:", "vulgate": "scriptura Ezechiae regis Iuda cum aegrotasset et convaluisset de infirmitate sua;", "brenton": "THE PRAYER OF EZEKIAS KING OF JUDEA, WHEN HE HAD BEEN SICK, AND WAS RECOVERED FROM HIS SICKNESS."}}, {"v": 10, "ref": "38:10", "o": "אֲנִ֣י אָמַ֗רְתִּי בִּ/דְמִ֥י יָמַ֛/י אֵלֵ֖כָה בְּ/שַׁעֲרֵ֣י שְׁא֑וֹל פֻּקַּ֖דְתִּי יֶ֥תֶר שְׁנוֹתָֽ/י", "en": {"kjv": "I said in the cutting off of my days, I shall go to the gates of the grave: I am deprived of the residue of my years.", "web": "I said, “In the middle of my life I go into the gates of Sheol. I am deprived of the residue of my years.”", "bsb": "I said, “In the prime of my life I must go through the gates of Sheol and be deprived of the remainder of my years.”", "asv": "I said, In the noontide of my days I shall go into the gates of Sheol: I am deprived of the residue of my years.", "ylt": "`I--I said in the cutting off of my days, I go in to the gates of Sheol, I have numbered the remnant of mine years.", "dra": "I said: In the midst of my days I shall go to the gates of hell: I sought for the residue of my years.", "bbe": "I said, In the quiet of my days I am going down into the underworld: the rest of my years are being taken away from me.", "geneva": "I saide in the cutting off of my dayes, I shall goe to the gates of the graue: I am depriued of the residue of my yeeres.", "wycliffe": "I seide, in the myddil of my daies Y schal go to the yatis of helle.", "rotherham": "I, said—In the noontide of my days, I must enter the gates of hades,—I am deprived of the residue of my years!", "darby": "I said, In the meridian of my days I shall go to the gates of Sheol: I am deprived of the rest of my years.", "twenty": "", "jps": "I said: In the noontide of my days I shall go, even to the gates of the nether-world; I am deprived of the residue of my years.", "acv": "I said, In the noontide of my days I shall go into the gates of Sheol. I am deprived of the residue of my years.", "anderson": "", "haweis": "", "noyes": "I said: \"Now, in the quiet of my days, shall I go down to the gates of the under-world; I am deprived of the residue of my years.\"", "webster": "I said in the cutting off of my days, I shall go to the gates of the grave: I am deprived of the residue of my years.", "vulgate": "ego dixi in dimidio dierum meorum vadam ad portas inferi quaesivi residuum annorum meorum;", "brenton": "I said in the end of my days, I shall go to the gates of the grave: I shall part with the remainder of my years."}}, {"v": 11, "ref": "38:11", "o": "אָמַ֨רְתִּי֙ לֹא אֶרְאֶ֣ה יָ֔הּ יָ֖הּ בְּ/אֶ֣רֶץ הַ/חַיִּ֑ים לֹא אַבִּ֥יט אָדָ֛ם ע֖וֹד עִם י֥וֹשְׁבֵי חָֽדֶל", "en": {"kjv": "I said, I shall not see the Lord, even the Lord, in the land of the living: I shall behold man no more with the inhabitants of the world.", "web": "I said, “I won’t see Yah, Yah in the land of the living. I will see man no more with the inhabitants of the world.", "bsb": "I said, “I will never again see the LORD, even the LORD, in the land of the living; I will no longer look on mankind with those who dwell in this world.", "asv": "I said, I shall not see Jehovah, even Jehovah in the land of the living: I shall behold man no more with the inhabitants of the world.", "ylt": "I said, I do not see Jah--Jah! In the land of the living, I do not behold man any more, With the inhabitants of the world.", "dra": "I said: I shall not see the Lord God in the land of the living. I shall behold man no more, nor the inhabitant of rest.", "bbe": "I said, I will not see the Lord, even the Lord in the land of the living: I will not see man again or those living in the world.", "geneva": "I said, I shall not see the Lord, euen the Lord in the land of the liuing: I shall see man no more among the inhabitants of the world.", "wycliffe": "Y souyte the residue of my yeeris; Y seide, Y schal not se the Lord God in the lond of lyueris; Y schal no more biholde a man, and a dwellere of reste.", "rotherham": "I said—I shall not see Yah, Yah, in the land of the living, I shall discern the son of earth no longer, with the dwellers in the quiet land.", "darby": "I said, I shall not see Jah, Jah in the land of the living. With those who dwell where all has ceased to be, I shall behold man no more.", "twenty": "", "jps": "I said: I shall not see HaShem, even HaShem in the land of the living; I shall behold man no more with the inhabitants of the world.", "acv": "I said, I shall not see Jehovah, even Jehovah in the land of the living. I shall behold man no more with the inhabitants of the world.", "anderson": "", "haweis": "", "noyes": "I said: \"No more shall I see Jehovah, Jehovah in the land of the living. I shall behold man no more Among the inhabitants of stillness.", "webster": "I said, I shall not see the LORD, [even] the LORD, in the land of the living: I shall behold man no more with the inhabitants of the world.", "vulgate": "dixi non videbo Dominum Dominum in terra viventium non aspiciam hominem ultra et habitatorem quievit;", "brenton": "I said, I shall no more at all see the salvation of God in the land of the living: I shall no more at all see the salvation of Israel on the earth: I shall no more at all see man."}}, {"v": 12, "ref": "38:12", "o": "דּוֹרִ֗/י נִסַּ֧ע וְ/נִגְלָ֛ה מִ/נִּ֖י כְּ/אֹ֣הֶל רֹעִ֑/י קִפַּ֨דְתִּי כָ/אֹרֵ֤ג חַיַּ/י֙ מִ/דַּלָּ֣ה יְבַצְּעֵ֔/נִי מִ/יּ֥וֹם עַד לַ֖יְלָה תַּשְׁלִימֵֽ/נִי", "en": {"kjv": "Mine age is departed, and is removed from me as a shepherd’s tent: I have cut off like a weaver my life: he will cut me off with pining sickness: from day even to night wilt thou make an end of me.", "web": "My dwelling is removed, and is carried away from me like a shepherd’s tent. I have rolled up, like a weaver, my life. He will cut me off from the loom. From day even to night you will make an end of me.", "bsb": "My dwelling has been picked up and removed from me like a shepherd’s tent. I have rolled up my life like a weaver; He cuts me off from the loom; from day until night You make an end of me.", "asv": "My dwelling is removed, and is carried away from me as a shepherd’s tent: I have rolled up, like a weaver, my life; he will cut me off from the loom: From day even to night wilt thou make an end of me.", "ylt": "My sojourning hath departed, And been removed from me as a shepherd's tent, I have drawn together, as a weaver, my life, By weakness it cutteth me off, From day unto night Thou dost end me.", "dra": "My generation is at an end, and it is rolled away from me, as a shepherd's tent. My life is cut off, as by a weaver: whilst I was yet but beginning, he cut me off: from morning even to night thou wilt make an end of me.", "bbe": "My resting-place is pulled up and taken away from me like a herdsman's tent: my life is rolled up like a linen-worker's thread; I am cut off from the cloth on the frame: from day even to night you give me up to pain.", "geneva": "Mine habitation is departed, and is remoued from me, like a shepheards tent: I haue cut off like a weauer my life: he will cut me off from the height: from day to night, thou wilt make an ende of me.", "wycliffe": "My generacioun is takun awei, and is foldid togidere fro me, as the tabernacle of scheepherdis is foldid togidere. Mi lijf is kit doun as of a webbe; he kittide doun me, the while Y was wouun yit. Fro the morewtid `til to the euentid thou schalt ende me;", "rotherham": "My dwelling, hath been broken up. And is stripped from me, like a shepherd’s tent,—I have rolled up—as a weaver—my life From the loom, doth he cut me off, From day until night, [I said] —Thou wilt finish me.", "darby": "Mine age is departed, and is removed from me as a shepherd's tent. I have cut off like a weaver my life. He separateth me from the thrum: — from day to night thou wilt make an end of me.", "twenty": "", "jps": "My habitation is plucked up and carried away from me as a shepherd's tent; I have rolled up like a weaver my life; He will cut me off from the thrum; from day even to night wilt Thou make an end of me.", "acv": "My dwelling is removed, and is carried away from me as a shepherd's tent. I have rolled up, like a weaver, my life. He will cut me off from the loom. From day even to night thou will make an end of me.", "anderson": "", "haweis": "", "noyes": "My habitation is torn away and removed from me, Like a shepherd’s tent; My life is rolled up as by the weaver; He cutteth me off from the thrum; Between morning and night wilt thou make an end of me!\"", "webster": "My age hath departed, and is removed from me as a shepherd's tent: I have cut off like a weaver my life: he will cut me off with pining sickness: from day [even] to night wilt thou make an end of me.", "vulgate": "generatio mea ablata est et convoluta est a me quasi tabernaculum pastorum praecisa est velut a texente vita mea dum adhuc ordirer succidit me de mane usque ad vesperam finies me;", "brenton": "My life has failed from among my kindred: I have parted with the remainder of my life: it has gone forth and departed from me, as one that having pitched a tent takes it down again: my breath was with me as a weaver's web, when she that weaves draws nigh to cut off the thread."}}, {"v": 13, "ref": "38:13", "o": "שִׁוִּ֤יתִי עַד בֹּ֨קֶר֙ כָּֽ/אֲרִ֔י כֵּ֥ן יְשַׁבֵּ֖ר כָּל עַצְמוֹתָ֑/י מִ/יּ֥וֹם עַד לַ֖יְלָה תַּשְׁלִימֵֽ/נִי", "en": {"kjv": "I reckoned till morning, that, as a lion, so will he break all my bones: from day even to night wilt thou make an end of me.", "web": "I waited patiently until morning. He breaks all my bones like a lion. From day even to night you will make an end of me.", "bsb": "I composed myself until the morning. Like a lion He breaks all my bones; from day until night You make an end of me.", "asv": "I quieted myself until morning; as a lion, so he breaketh all my bones: From day even to night wilt thou make an end of me.", "ylt": "I have set Him till morning as a lion, So doth He break all my bones, From day unto night Thou dost end me.", "dra": "I hoped till morning, as a lion so hath he broken all my bones: from morning even to night thou wilt make an end of me.", "bbe": "I am crying out with pain till the morning; it is as if a lion was crushing all my bones.", "geneva": "I rekoned to the morning: but he brake all my bones, like a lion: from day to night wilt thou make an ende of me.", "wycliffe": "Y hopide til to the morewtid; as a lioun, so he al to-brak alle my boonys. Fro the morewtid til to the euentid thou schalt ende me; as the brid of a swalewe, so Y schal crie;", "rotherham": "I cried out, until morning, like a lion, Thus, will he break all my bones! From day until night, Thou wilt finish me!", "darby": "I kept still until the morning; ...as a lion, so doth he break all my bones. From day to night thou wilt make an end of me.", "twenty": "", "jps": "The more I make myself like unto a lion until morning, the more it breaketh all my bones; from day even to night wilt Thou make an end of me.", "acv": "I quieted myself until morning. As a lion, so he breaks all my bones. From day even to night will thou make an end of me.", "anderson": "", "haweis": "", "noyes": "I waited till morning, and like a lion Did he crush all my bones; \"Between morning and night wilt thou make an end of me!\"", "webster": "I reckoned till morning, [that], as a lion, so will he break all my bones: from day [even] to night wilt thou make an end of me.", "vulgate": "sperabam usque ad mane quasi leo sic contrivit omnia ossa mea de mane usque ad vesperam finies me;", "brenton": "In that day I was given up as to a lion until the morning: so has he broken all my bones: for I was so given up from day even to night."}}, {"v": 14, "ref": "38:14", "o": "כְּ/ס֤וּס עָגוּר֙ כֵּ֣ן אֲצַפְצֵ֔ף אֶהְגֶּ֖ה כַּ/יּוֹנָ֑ה דַּלּ֤וּ עֵינַ/י֙ לַ/מָּר֔וֹם אֲדֹנָ֖/י עָֽשְׁקָה לִּ֥/י עָרְבֵֽ/נִי", "en": {"kjv": "Like a crane or a swallow, so did I chatter: I did mourn as a dove: mine eyes fail with looking upward: O Lord, I am oppressed; undertake for me.", "web": "I chattered like a swallow or a crane. I moaned like a dove. My eyes weaken looking upward. Lord, I am oppressed. Be my security.”", "bsb": "I chirp like a swallow or crane; I moan like a dove. My eyes grow weak as I look upward. O Lord, I am oppressed; be my security.”", "asv": "Like a swallowora crane, so did I chatter; I did moan as a dove; mine eyes fail with looking upward: O Lord, I am oppressed, be thou my surety.", "ylt": "As a crane--a swallow--so I chatter, I mourn as a dove, Drawn up have been mine eyes on high, O Jehovah, oppression is on me, be my surety.", "dra": "I will cry like a young swallow, I will meditate like a dove: my eyes are weakened looking upward: Lord, I suffer violence, answer thou for me.", "bbe": "I make cries like a bird; I give out sounds of grief like a dove: my eyes are looking up with desire; O Lord, I am crushed, take up my cause.", "geneva": "Like a crane or a swallow, so did I chatter: I did mourne as a doue: mine eies were lift vp on high: O Lord, it hath oppressed me, comfort me.", "wycliffe": "Y schal bithenke as a culuer. Myn iyen biholdynge an hiy, ben maad feble. Lord, Y suffre violence, answere thou for me; what schal Y seie,", "rotherham": "As a twittering swallow, so, do I chatter, I coo as a dove,—Mine eyes languish through looking on high, O My Lord! distress is upon me—my Surety!", "darby": "Like a swallow [or] a crane, so did I chatter; I mourned as a dove; mine eyes failed [with looking] upward: Lord, I am oppressed; undertake for me.", "twenty": "", "jps": "Like a swallow or a crane, so do I chatter, I do moan as a dove; mine eyes fail with looking upward. O HaShem, I am oppressed, be Thou my surety.", "acv": "Like a swallow or a crane, so I chattered. I moaned as a dove. My eyes fail with looking upward. O Lord, I am oppressed, be thou my surety.", "anderson": "", "haweis": "", "noyes": "Like a swallow or a crane, so did I twitter; I did mourn as a dove; Mine eyes failed with looking upward; \"O Lord, I am in distress; O, deliver me!\"", "webster": "Like a crane [or] a swallow, so I chattered: I mourned as a dove: my eyes fail [with looking] upward: O LORD, I am oppressed; undertake for me.", "vulgate": "sicut pullus hirundinis sic clamabo meditabor ut columba adtenuati sunt oculi mei suspicientes in excelsum Domine vim patior sponde pro me;", "brenton": "As a swallow, so will I cry, and as a dove, so do I mourn: for mine eyes have failed with looking to the height of heaven to the Lord, who has delivered me, and removed the sorrow of my soul."}}, {"v": 15, "ref": "38:15", "o": "מָֽה אֲדַבֵּ֥ר וְ/אָֽמַר לִ֖/י וְ/ה֣וּא עָשָׂ֑ה אֶדַּדֶּ֥ה כָל שְׁנוֹתַ֖/י עַל מַ֥ר נַפְשִֽׁ/י", "en": {"kjv": "What shall I say? he hath both spoken unto me, and himself hath done it: I shall go softly all my years in the bitterness of my soul.", "web": "What will I say? He has both spoken to me, and himself has done it. I will walk carefully all my years because of the anguish of my soul.", "bsb": "What can I say? He has spoken to me, and He Himself has done this. I will walk slowly all my years because of the anguish of my soul.", "asv": "What shall I say? he hath both spoken unto me, and himself hath done it: I shall go softly all my years because of the bitterness of my soul.", "ylt": "--What do I say? seeing He said to me, And He Himself hath wrought, I go softly all my years for the bitterness of my soul.", "dra": "What shall I say, or what shall he answer for me, whereas he himself hath done it? I will recount to thee all my years in the bitterness of my soul.", "bbe": "What am I to say? seeing that it is he who has done it: all my time of sleeping I am turning from side to side without rest.", "geneva": "What shall I say? for he hath said it to me, and he hath done it: I shall walke weakely all my yeeres in the bitternesse of my soule.", "wycliffe": "ether what schal answere to me, whanne `I mysilf haue do? Y schal bithenke to thee alle my yeeris, in the bitternisse of my soule.", "rotherham": "What can I say? Since he hath promised for me, Himself, will perform. I will go softly, all my years. Because of the bitterness of my soul,", "darby": "What shall I say? He hath both spoken unto me, and himself hath done [it]. I shall go softly all my years in the bitterness of my soul.", "twenty": "", "jps": "What shall I say? He hath both spoken unto me, and Himself hath done it; I shall go softly all my years for the bitterness of my soul.", "acv": "What shall I say? He has both spoken to me, and himself has done it. I shall go softly all my years because of the bitterness of my soul.", "anderson": "", "haweis": "", "noyes": "What shall I say? He promised it, and he hath done it; I will walk humbly all my life On account of the bitterness of my soul.", "webster": "What shall I say? he hath both spoken to me, and himself hath done [it]: I shall go softly all my years in the bitterness of my soul.", "vulgate": "quid dicam aut quid respondebit mihi cum ipse fecerit recogitabo omnes annos meos in amaritudine animae meae;", "brenton": ""}}, {"v": 16, "ref": "38:16", "o": "אֲדֹנָ֖/י עֲלֵי/הֶ֣ם יִֽחְי֑וּ וּ/לְ/כָל בָּ/הֶן֙ חַיֵּ֣י רוּחִ֔/י וְ/תַחֲלִימֵ֖/נִי וְ/הַחֲיֵֽ/נִי", "en": {"kjv": "O Lord, by these things men live, and in all these things is the life of my spirit: so wilt thou recover me, and make me to live.", "web": "Lord, men live by these things; and my spirit finds life in all of them: you restore me, and cause me to live.", "bsb": "O Lord, by such things men live, and in all of them my spirit finds life. You have restored me to health and have let me live.", "asv": "O Lord, by these things men live; And wholly therein is the life of my spirit: Wherefore recover thou me, and make me to live.", "ylt": "Lord, by these do men live, And by all in them is the life of my spirit, And Thou savest me, make me also to live,", "dra": "O Lord, if man's life be such, and the life of my spirit be in such things as these, thou shalt correct me, and make me to live.", "bbe": "O Lord, for this cause I am waiting for you, give rest to my spirit: make me well again, and let me come back to life.", "geneva": "O Lord, to them that ouerliue them, and to all that are in them, the life of my spirite shalbe knowen, that thou causedst me to sleepe and hast giuen life to me.", "wycliffe": "Lord, if me lyueth so, and the lijf of my spirit is in siche thingis, thou schalt chastise me, and schalt quykene me.", "rotherham": "O My Lord! on those things do men live,—And, altogether in them, is the life of my spirit, When thou hast strengthened me and made me live.", "darby": "Lord, by these things [men] live, and in all these things is the life of my spirit; and thou hast recovered me, and made me to live.", "twenty": "", "jps": "O L-rd, by these things men live, and altogether therein is the life of my spirit; wherefore recover Thou me, and make me to live.", "acv": "O Lord, by these things men live, and wholly therein is the life of my spirit. Therefore recover thou me, and make me to live.", "anderson": "", "haweis": "", "noyes": "Lord, it is thus that men live; From thee alone cometh the life of my spirit; Thou hast restored me, and caused me to live.", "webster": "O Lord, by these [things men] live, and in all these [things is] the life of my spirit: so wilt thou recover me, and make me to live.", "vulgate": "Domine sic vivitur et in talibus vita spiritus mei corripies me et vivificabis me;", "brenton": "Yea, O Lord, for it was told thee concerning this; and thou hast revived my breath; and I am comforted, and live."}}, {"v": 17, "ref": "38:17", "o": "הִנֵּ֥ה לְ/שָׁל֖וֹם מַר לִ֣/י מָ֑ר וְ/אַתָּ֞ה חָשַׁ֤קְתָּ נַפְשִׁ/י֙ מִ/שַּׁ֣חַת בְּלִ֔י כִּ֥י הִשְׁלַ֛כְתָּ אַחֲרֵ֥י גֵוְ/ךָ֖ כָּל חֲטָאָֽ/י", "en": {"kjv": "Behold, for peace I had great bitterness: but thou hast in love to my soul delivered it from the pit of corruption: for thou hast cast all my sins behind thy back.", "web": "Behold, for peace I had great anguish, but you have in love for my soul delivered it from the pit of corruption; for you have cast all my sins behind your back.", "bsb": "Surely for my own welfare I had such great anguish; but Your love has delivered me from the pit of oblivion, for You have cast all my sins behind Your back.", "asv": "Behold, it wasformypeacethatI had great bitterness: But thou hast in love to my soul delivered it from the pit of corruption; For thou hast cast all my sins behind thy back.", "ylt": "Lo, to peace He changed for me bitterness, And Thou hast delighted in my soul without corruption, For Thou hast cast behind Thy back all my sins.", "dra": "Behold in peace is my bitterness most bitter: but thou hast delivered my soul that it should not perish, thou hast cast all my sins behind thy back.", "bbe": "See, in place of peace my soul had bitter sorrow. but you have kept back my soul from the underworld; for you have put all my sins out of your memory.", "geneva": "Beholde, for felicitie I had bitter griefe, but it was thy pleasure to deliuer my soule from the pit of corruption: for thou hast cast all my sinnes behinde thy backe.", "wycliffe": "Lo! my bitternesse is moost bittir in pees; forsothe thou hast delyuered my soule, that it perischide not; thou hast caste awey bihynde thi bak alle my synnes.", "rotherham": "Lo! for well-being, I had bitterness—bitterness,—But, thou, cleaving unto my soul, hast raised me from the pit of corruption, For thou hast cast, behind thy back all my sins.", "darby": "Behold, instead of peace I had bitterness upon bitterness; but thou hast in love delivered my soul from the pit of destruction; for thou hast cast all my sins behind thy back.", "twenty": "", "jps": "Behold, for my peace I had great bitterness; but Thou hast in love to my soul delivered it from the pit of corruption; for Thou hast cast all my sins behind Thy back.", "acv": "Behold, for peace I had great bitterness. But thou have by love for my soul delivered it from the pit of corruption. For thou have cast all my sins behind thy back.", "anderson": "", "haweis": "", "noyes": "Behold, my anguish is changed into ease; In love thou hast delivered me from the pit of destruction; Thou hast cast all my sins behind thy back.", "webster": "Behold, for peace I had great bitterness: but thou hast in love to my soul [delivered it] from the pit of corruption: for thou hast cast all my sins behind thy back.", "vulgate": "ecce in pace amaritudo mea amarissima tu autem eruisti animam meam ut non periret proiecisti post tergum tuum omnia peccata mea;", "brenton": "For thou hast chosen my soul, that it should not perish: and thou hast cast all my sins behind me."}}, {"v": 18, "ref": "38:18", "o": "כִּ֣י לֹ֥א שְׁא֛וֹל תּוֹדֶ֖/ךָּ מָ֣וֶת יְהַלְלֶ֑/ךָּ לֹֽא יְשַׂבְּר֥וּ יֽוֹרְדֵי ב֖וֹר אֶל אֲמִתֶּֽ/ךָ", "en": {"kjv": "For the grave cannot praise thee, death can not celebrate thee: they that go down into the pit cannot hope for thy truth.", "web": "For Sheol can’t praise you. Death can’t celebrate you. Those who go down into the pit can’t hope for your truth.", "bsb": "For Sheol cannot thank You; Death cannot praise You. Those who descend to the Pit cannot hope for Your faithfulness.", "asv": "For Sheol cannot praise thee, death cannot celebrate thee: They that go down into the pit cannot hope for thy truth.", "ylt": "For Sheol doth not confess Thee, Death doth not praise Thee, Those going down to the pit hope not for Thy truth.", "dra": "For hell shall not confess to thee, neither shall death praise thee: nor shall they that go down into the pit, look for thy truth.", "bbe": "For the underworld is not able to give you praise, death gives you no honour: for those who go down into the underworld there is no hope in your mercy.", "geneva": "For the graue cannot confesse thee: death cannot praise thee: they that goe downe into the pit, cannot hope for thy trueth.", "wycliffe": "For not helle schal knowleche to thee, nethir deth schal herie thee; thei that goon doun in to the lake, schulen not abide thi treuthe.", "rotherham": "For, hades, cannot praise thee Nor, death, celebrate thee,—They who go down to the pit cannot wait for thy faithfulness.", "darby": "For not Sheol shall praise thee, nor death celebrate thee; they that go down into the pit do not hope for thy truth.", "twenty": "", "jps": "For the nether-world cannot praise Thee, death cannot celebrate Thee; they that go down into the pit cannot hope for Thy truth.", "acv": "For Sheol cannot praise thee, death cannot celebrate thee. Those who go down into the pit cannot hope for thy truth.", "anderson": "", "haweis": "", "noyes": "For the under-world cannot praise thee; The realms of death cannot celebrate thee; They that go down to the pit cannot wait for thy faithfulness.", "webster": "For the grave cannot praise thee, death can [not] celebrate thee: they that go down into the pit cannot hope for thy truth.", "vulgate": "quia non infernus confitebitur tibi neque mors laudabit te non expectabunt qui descendunt in lacum veritatem tuam;", "brenton": "For they that are in the grave shall not praise thee, neither shall the dead bless thee, neither shall they that are in Hades hope for thy mercy."}}, {"v": 19, "ref": "38:19", "o": "חַ֥י חַ֛י ה֥וּא יוֹדֶ֖/ךָ כָּמ֣וֹ/נִי הַ/יּ֑וֹם אָ֣ב לְ/בָנִ֔ים יוֹדִ֖יעַ אֶל אֲמִתֶּֽ/ךָ", "en": {"kjv": "The living, the living, he shall praise thee, as I do this day: the father to the children shall make known thy truth.", "web": "The living, the living, he shall praise you, as I do this day. The father shall make known your truth to the children.", "bsb": "The living, only the living, can thank You, as I do today; fathers will tell their children about Your faithfulness.", "asv": "The living, the living, he shall praise thee, as I do this day: The father to the children shall make known thy truth.", "ylt": "The living, the living, he doth confess Thee.", "dra": "The living, the living, he shall give praise to thee, as I do this day: the father shall make the truth known to the children.", "bbe": "The living, the living man, he will give you praise, as I do this day: the father will give the story of your mercy to his children.", "geneva": "But the liuing, the liuing, he shall confesse thee, as I doe this day: the father to the children shall declare thy trueth.", "wycliffe": "A lyuynge man, a lyuynge man, he schal knouleche to thee, as and Y to dai; the fadir schal make knowun thi treuthe to sones.", "rotherham": "The living, the living, he, can praise thee, As I do this day,—A father, to his children, can make known thy faithfulness.", "darby": "The living, the living, he shall praise thee, as I this day: the father to the children shall make known thy truth.", "twenty": "", "jps": "The living, the living, he shall praise Thee, as I do this day; the father to the children shall make known Thy truth.", "acv": "The living, the living, he shall praise thee, as I do this day. The father to the sons shall make known thy truth.", "anderson": "", "haweis": "", "noyes": "The living, the living praise thee, as I do this day; The father to the children shall make known thy faithfulness.", "webster": "The living, the living, he shall praise thee, as I [do] this day: the father to the children shall make known thy truth.", "vulgate": "vivens vivens ipse confitebitur tibi sicut et ego hodie pater filiis notam faciet veritatem tuam;", "brenton": "The living shall bless thee, as I also do: for from this day shall I beget children, who shall declare thy righteousness,"}}, {"v": 20, "ref": "38:20", "o": "יְהוָ֖ה לְ/הוֹשִׁיעֵ֑/נִי וּ/נְגִנוֹתַ֧י נְנַגֵּ֛ן כָּל יְמֵ֥י חַיֵּ֖י/נוּ עַל בֵּ֥ית יְהוָֽה", "en": {"kjv": "The Lord was ready to save me: therefore we will sing my songs to the stringed instruments all the days of our life in the house of the Lord.", "web": "Yahweh will save me. Therefore we will sing my songs with stringed instruments all the days of our life in Yahweh’s house.", "bsb": "The LORD will save me; we will play songs on stringed instruments all the days of our lives in the house of the LORD.", "asv": "Jehovah isreadyto save me: Therefore we will sing my songs with stringed instruments All the days of our life in the house of Jehovah.", "ylt": "Like myself to-day--a father to sons Doth make known of Thy faithfulness, O Jehovah--to save me: And my songs we sing all days of our lives In the house of Jehovah.'", "dra": "O Lord, save me, and we will sing our psalms all the days of our life in the house of the Lord.", "bbe": "O Lord, quickly be my saviour; so we will make my songs to corded instruments all the days of our lives in the house of the Lord.", "geneva": "The Lord was ready to saue me: therefore we will sing my song, all the dayes of our life in the House of the Lord.", "wycliffe": "Lord, make thou me saaf, and we schulen synge oure salmes in all the daies of oure lijf in the hous of the Lord.", "rotherham": "Yahweh, [was willing] to save me,—Therefore, on my stringed instruments, will we play—All the days of our life By the house of Yahweh.", "darby": "Jehovah was [purposed] to save me. — And we will play upon my stringed instruments all the days of our life, in the house of Jehovah.", "twenty": "", "jps": "HaShem is ready to save me; therefore we will sing songs to the stringed instruments all the days of our life in the house of HaShem.", "acv": "Jehovah is ready to save me. Therefore we will sing my songs with stringed instruments all the days of our life in the house of Jehovah.", "anderson": "", "haweis": "", "noyes": "Jehovah hath saved me; Therefore will we sing our songs with stringed instruments, All the days of our life, In the house of Jehovah.", "webster": "The LORD [was ready] to save me: therefore we will sing my songs to the stringed instruments all the days of our life in the house of the LORD.", "vulgate": "Domine salvum me fac et psalmos nostros cantabimus cunctis diebus vitae nostrae in domo Domini;", "brenton": "O God of my salvation; and I will not cease blessing thee with the psaltery all the days of my life before the house of God."}}, {"v": 21, "ref": "38:21", "o": "וַ/יֹּ֣אמֶר יְשַׁעְיָ֔הוּ יִשְׂא֖וּ דְּבֶ֣לֶת תְּאֵנִ֑ים וְ/יִמְרְח֥וּ עַֽל הַ/שְּׁחִ֖ין וְ/יֶֽחִי", "en": {"kjv": "For Isaiah had said, Let them take a lump of figs, and lay it for a plaister upon the boil, and he shall recover.", "web": "Now Isaiah had said, “Let them take a cake of figs, and lay it for a poultice on the boil, and he shall recover.”", "bsb": "Now Isaiah had said, “Prepare a lump of pressed figs and apply it to the boil, and he will recover.”", "asv": "Now Isaiah had said, Let them take a cake of figs, and lay it for a plaster upon the boil, and he shall recover.", "ylt": "And Isaiah saith, `Let them take a bunch of figs, and plaster over the ulcer, and he liveth.'", "dra": "Now Isaiah had ordered that they should take a lump of figs, and lay it as a plaster upon the wound, and that he should be healed.", "bbe": "And Isaiah said, Let them take a cake of figs, and put it on the diseased place, and he will get well.", "geneva": "Then said Isaiah, Take a lumpe of drye figs and lay it vpon the boyle, and he shall recouer.", "wycliffe": "And Ysaie comaundide, that thei schulden take a gobet of figus, and make a plaster on the wounde; and it schulde be heelid.", "rotherham": "And Isaiah had said, Let them take a cake of figs, and let them press it over the boil, that he may recover.", "darby": "Now Isaiah had said, Let them take a cake of figs, and lay it for a plaster upon the boil, and he shall recover.", "twenty": "", "jps": "And Isaiah said: 'Let them take a cake of figs, and lay it for a plaster upon the boil, and he shall recover.'", "acv": "Now Isaiah had said, Let them take a cake of figs, and lay it for a plaster upon the boil, and he shall recover.", "anderson": "", "haweis": "", "noyes": "Now Isaiah had said, let them take a lump of figs, and bruise them, and lay them upon the ulcer, and he shall recover.", "webster": "For Isaiah had said, Let them take a lump of figs, and lay [it] for a plaster upon the boil, and he will recover.", "vulgate": "et iussit Isaias ut tollerent massam de ficis et cataplasmarent super vulnus et sanaretur;", "brenton": "Now Esaias had said to Ezekias; Take a cake of figs, and mash them, and apply them as a plaster, and thou shalt be well."}}, {"v": 22, "ref": "38:22", "o": "וַ/יֹּ֥אמֶר חִזְקִיָּ֖הוּ מָ֣ה א֑וֹת כִּ֥י אֶעֱלֶ֖ה בֵּ֥ית יְהוָֽה", "en": {"kjv": "Hezekiah also had said, What is the sign that I shall go up to the house of the Lord?", "web": "Hezekiah also had said, “What is the sign that I will go up to Yahweh’s house?”", "bsb": "And Hezekiah had asked, “What will be the sign that I will go up to the house of the LORD?”", "asv": "Hezekiah also had said, What is the sign that I shall go up to the house of Jehovah?", "ylt": "And Hezekiah saith, `What is the sign that I go up to the house of Jehovah!'", "dra": "And Ezechias had said: What shall be the sign that I shall go up to the house of the Lord?", "bbe": "And Hezekiah said, What is the sign that I will go up to the house of the Lord?", "geneva": "Also Hezekiah had said, What is ye signe, that I shall goe vp into the House of the Lord?", "wycliffe": "And Ezechie seide, What signe schal be, that Y schal stie in to the hous of the Lord?", "rotherham": "And Hezekiah had said—What is the sign—that I shall go up unto the house of Yahweh?", "darby": "And Hezekiah had said, What is the sign that I shall go up into the house of Jehovah?", "twenty": "", "jps": "And Hezekiah said. 'What is the sign that I shall go up to the house of HaShem?'", "acv": "Hezekiah also had said, What is the sign that I shall go up to the house of Jehovah?", "anderson": "", "haweis": "", "noyes": "Hezekiah also had said, What is the sign that I shall go up to the house of Jehovah?", "webster": "Hezekiah also had said, What [is] the sign that I shall go up to the house of the LORD?", "vulgate": "et dixit Ezechias quod erit signum quia ascendam in domo Domini;", "brenton": "And Ezekias said, This is a sign to Ezekias, that I shall go up to the house of God."}}]}, {"c": 39, "verses": [{"v": 1, "ref": "39:1", "o": "בָּ/עֵ֣ת הַ/הִ֡וא שָׁלַ֡ח מְרֹדַ֣ךְ בַּ֠לְאֲדָן בֶּֽן בַּלְאֲדָ֧ן מֶֽלֶךְ בָּבֶ֛ל סְפָרִ֥ים וּ/מִנְחָ֖ה אֶל חִזְקִיָּ֑הוּ וַ/יִּשְׁמַ֕ע כִּ֥י חָלָ֖ה וַֽ/יֶּחֱזָֽק", "en": {"kjv": "At that time Merodach–baladan, the son of Baladan, king of Babylon, sent letters and a present to Hezekiah: for he had heard that he had been sick, and was recovered.", "web": "At that time, Merodach Baladan the son of Baladan, king of Babylon, sent letters and a present to Hezekiah; for he heard that he had been sick, and had recovered.", "bsb": "At that time Merodach-baladan son of Baladan king of Babylon sent letters and a gift to Hezekiah, for he had heard about Hezekiah’s illness and recovery.", "asv": "At that time Merodach-baladan the son of Baladan, king of Babylon, sent letters and a present to Hezekiah; for he heard that he had been sick, and was recovered.", "ylt": "At that time hath Merodach-Baladan, son of Baladan, king of Babylon, sent letters and a present unto Hezekiah, when he heareth that he hath been sick, and is become strong.", "dra": "At that time Merodach Baladan, the son of Baladan king of Babylon, sent letters and presents to Ezechias: for he had heard that he had been sick and was recovered.", "bbe": "At that time Merodach-baladan, the son of Baladan, king of Babylon, sent letters with an offering to Hezekiah, because he had news that Hezekiah had been ill, and was well again.", "geneva": "At the same time, Merodach Baladan, the sonne of Baladan, King of Babel, sent letters, and a present to Hezekiah: for he had heard that he had bene sicke, and was recouered.", "wycliffe": "In that tyme Marodach Baladan, the sone of Baladam, the kyng of Babiloyne, sente bookis and yiftis to Ezechie; for he hadde herd, that Ezechie hadde be sijk, and was rekyuerid.", "rotherham": "At that time, Merodach-baladan son of Baladan, king of Babylon, sent letters and a present unto Hezekiah,—for he had heard that Hezekiah had been sick, and had recovered.", "darby": "At that time Merodach-Baladan, the son of Baladan, king of Babylon, sent a letter and a present to Hezekiah; for he had heard that he had been sick and had recovered.", "twenty": "", "jps": "At that time Merodach-baladan the son of Baladan, king of Babylon, sent a letter and a present to Hezekiah; for he heard that he had been sick, and was recovered.", "acv": "At that time Merodach-baladan the son of Baladan, king of Babylon, sent letters and a present to Hezekiah, for he heard that he had been sick, and was recovered.", "anderson": "", "haweis": "", "noyes": "At that time Merodach Baladan, the son of Baladan, king of Babylon, sent a letter and a present to Hezekiah, for he had heard that he had been sick and was recovered.", "webster": "At that time Merodach-baladan, the son of Baladan, king of Babylon, sent letters and a present to Hezekiah: for he had heard that he had been sick, and had recovered.", "vulgate": "in tempore illo misit Marodach Baladan filius Baladan rex Babylonis libros et munera ad Ezechiam audierat enim quod aegrotasset et convaluisset;", "brenton": "At that time Marodach Baladan, the son of Baladan, the king of Babylonia, sent letters and ambassadors and gifts to Ezekias: for he had heard that he had been sick even to death, and was recovered."}}, {"v": 2, "ref": "39:2", "o": "וַ/יִּשְׂמַ֣ח עֲלֵי/הֶם֮ חִזְקִיָּהוּ֒ וַ/יַּרְאֵ֣/ם אֶת בֵּ֣ית נכת/ה נְכֹת֡/וֹ אֶת הַ/כֶּסֶף֩ וְ/אֶת הַ/זָּהָ֨ב וְ/אֶת הַ/בְּשָׂמִ֜ים וְ/אֵ֣ת הַ/שֶּׁ֣מֶן הַ/טּ֗וֹב וְ/אֵת֙ כָּל בֵּ֣ית כֵּלָ֔י/ו וְ/אֵ֛ת כָּל אֲשֶׁ֥ר נִמְצָ֖א בְּ/אֹֽצְרֹתָ֑י/ו לֹֽא הָיָ֣ה דָבָ֗ר אֲ֠שֶׁר לֹֽא הֶרְאָ֧/ם חִזְקִיָּ֛הוּ בְּ/בֵית֖/וֹ וּ/בְ/כָל מֶמְשַׁלְתּֽ/וֹ", "en": {"kjv": "And Hezekiah was glad of them, and shewed them the house of his precious things, the silver, and the gold, and the spices, and the precious ointment, and all the house of his armour, and all that was found in his treasures: there was nothing in his house, nor in all his dominion, that Hezekiah shewed them not.", "web": "Hezekiah was pleased with them, and showed them the house of his precious things, the silver, and the gold, the spices, and the precious oil, and all the house of his armor, and all that was found in his treasures. There was nothing in his house, nor in all his dominion, that Hezekiah didn’t show them.", "bsb": "And Hezekiah welcomed the envoys gladly and showed them what was in his treasure house—the silver, the gold, the spices, and the precious oil, as well as his entire armory—all that was found in his storehouses. There was nothing in his palace or in all his dominion that Hezekiah did not show them.", "asv": "And Hezekiah was glad of them, and showed them the house of his precious things, the silver, and the gold, and the spices, and the precious oil, and all the house of his armor, and all that was found in his treasures: there was nothing in his house, nor in all his dominion, that Hezekiah showed them not.", "ylt": "And Hezekiah rejoiceth over them, and sheweth them the house of his spices, the silver, and the gold, and the spices, and the good ointment, and all the house of his vessels, and all that hath been found in his treasures; there hath not been a thing in his house, and in all his dominion, that Hezekiah hath not shewed them.", "dra": "And Ezechias rejoiced at their coming, and he shewed them the storehouses of his aromatical spices, and of the silver, and of the gold, and of the sweet odours, and of the precious ointment, and all the storehouses of his furniture, and all things that were found in his treasures. There was nothing in his house, nor in all his dominion that Ezechias shewed them not.", "bbe": "And Hezekiah was glad at their coming, and let them see all his store of wealth, the silver and the gold and the spices and the oil, and all the house of his arms, and everything there was in his stores: there was nothing in all his house or his kingdom which he did not let them see.", "geneva": "And Hezekiah was glad of them, and shewed them the house of the treasures, the siluer, and the golde, and the spices, and the precious ointment, and all the house of his armour, and all that was founde in his treasures: there was nothing in his house, nor in all his kingdome that Hezekiah shewed them not.", "wycliffe": "Forsothe Ezechie was glad on hem, and schewide to hem the selle of swete smellynge spices, and of siluer, and of gold, and of smellynge thingis, and of best oynement, and alle the schoppis of his purtenaunce of houshold, and alle thingis that weren foundun in hise tresours; no word was, which Ezechie schewide not to hem in his hous, and in al his power.", "rotherham": "And Hezekiah, rejoiced over them, and showed them his house of precious things—the silver and the gold and the spices and the precious ointment and all his armoury—and all that was found among his treasures,—there was nothing, which Hezekiah, did not show them—in his house or in all his dominion.", "darby": "And Hezekiah was glad of them, and shewed them the house of his precious things, the silver and the gold, and the spices and the fine oil, and all the house of his armour, and all that was found amongst his treasures: there was nothing in his house, nor in all his dominion, that Hezekiah did not shew them.", "twenty": "", "jps": "And Hezekiah was glad of them, and showed them his treasure-house, the silver, and the gold, and the spices, and the precious oil, and all the house of his armour, and all that was found in his treasures; there was nothing in his house, nor in all his dominion, that Hezekiah showed them not.", "acv": "And Hezekiah was glad of them, and showed them the house of his precious things, the silver, and the gold, and the spices, and the precious oil, and all the house of his armor, and all that was found in his treasures. There was nothing in his house, nor in all his dominion, that Hezekiah did not show them.", "anderson": "", "haweis": "", "noyes": "And Hezekiah was delighted with them, and showed the embassy his treasure-house, the silver, and the gold, and the spices, and the precious oil, and his whole armory, and all that was found in his treasures. There was nothing in his house, nor in all his dominion, which Hezekiah did not show them.", "webster": "And Hezekiah was glad of them, and showed them the house of his precious things, the silver, and the gold, and the spices, and the precious ointment, and all the house of his armor, and all that was found in his treasures: there was nothing in his house, nor in all his dominion, that Hezekiah did not show them.", "vulgate": "laetatus est autem super eis Ezechias et ostendit eis cellam aromatum et argenti et auri et odoramentorum et unguenti optimi et omnes apothecas supellectilis suae et universa quae inventa sunt in thesauris eius non fuit verbum quod non ostenderet eis Ezechias in domo sua et in omni potestate sua;", "brenton": "And Ezekias was glad of their coming, and he shewed them the house of his spices, and of silver, and gold, and myrrh, and incense, and ointment, and all the houses of his treasures, and all that he had in his stores: and there was nothing in his house, nor in all his dominion, which Ezekias did not shew."}}, {"v": 3, "ref": "39:3", "o": "וַ/יָּבֹא֙ יְשַׁעְיָ֣הוּ הַ/נָּבִ֔יא אֶל הַ/מֶּ֖לֶךְ חִזְקִיָּ֑הוּ וַ/יֹּ֨אמֶר אֵלָ֜י/ו מָ֥ה אָמְר֣וּ הָ/אֲנָשִׁ֣ים הָ/אֵ֗לֶּה וּ/מֵ/אַ֨יִן֙ יָבֹ֣אוּ אֵלֶ֔י/ךָ וַ/יֹּ֨אמֶר֙ חִזְקִיָּ֔הוּ מֵ/אֶ֧רֶץ רְחוֹקָ֛ה בָּ֥אוּ אֵלַ֖/י מִ/בָּבֶֽל", "en": {"kjv": "Then came Isaiah the prophet unto king Hezekiah, and said unto him, What said these men? and from whence came they unto thee? And Hezekiah said, They are come from a far country unto me, even from Babylon.", "web": "Then Isaiah the prophet came to king Hezekiah, and asked him, “What did these men say? Where did they come from to you?” Hezekiah said, “They have come from a country far from me, even from Babylon.”", "bsb": "Then the prophet Isaiah went to King Hezekiah and asked, “Where did those men come from, and what did they say to you?” “They came to me from a distant land,” Hezekiah replied, “from Babylon.”", "asv": "Then came Isaiah the prophet unto king Hezekiah, and said unto him, What said these men? and from whence came they unto thee? And Hezekiah said, They are come from a far country unto me, even from Babylon.", "ylt": "And Isaiah the prophet cometh in unto king Hezekiah, and saith unto him, `What said these men? and whence come they unto thee?' And Hezekiah saith, `From a land afar off they have come unto me--from Babylon.'", "dra": "Then Isaiah the prophet came to king Ezechias, and said to him: What said these men, and from whence came they to thee? And Ezechias said: From a far country they came to me, from Babylon.", "bbe": "Then Isaiah the prophet came to King Hezekiah, and said to him, What did these men say, and where did they come from? And Hezekiah said, They came from a far country, even from Babylon.", "geneva": "Then came Isaiah the Prophet vnto King Hezekiah, and said vnto him, What said these men? and from whence came they to thee? And Hezekiah saide, They are come from a farre countrey vnto me, from Babel.", "wycliffe": "Sotheli Ysaie, the prophete, entride to kyng Ezechie, and seide to hym, What seiden thes men, and fro whennus camen thei to thee? And Ezechie seide, Fro a fer lond thei camen to me, fro Babiloyne.", "rotherham": "Then came Isaiah the prophet, unto King Hezekiah,—and said unto him—What said these men? and whence came they unto thee? And Hezekiah said, From a land far away, came they unto me, from Babylon!", "darby": "Then came the prophet Isaiah to king Hezekiah, and said to him, What said these men? and from whence came they to thee? And Hezekiah said, They came from a far country to me, from Babylon.", "twenty": "", "jps": "Then came Isaiah the prophet unto king Hezekiah, and said unto him: 'What said these men? and from whence came they unto thee?' And Hezekiah said: 'They are come from a far country unto me, even from Babylon.'", "acv": "Then Isaiah the prophet came to king Hezekiah, and said to him, What did these men say? And from where did they come to thee? And Hezekiah said, They have come from a far country to me, even from Babylon.", "anderson": "", "haweis": "", "noyes": "Then came Isaiah the prophet to King Hezekiah, and said to him, What did these men say, and whence did they come to thee? And Hezekiah said, They came to me from a distant country, from Babylon.", "webster": "Then came Isaiah the prophet to king Hezekiah, and said to him, What said these men? and from whence came they to thee? and Hezekiah said, They have come to me from a far country, [even] from Babylon.", "vulgate": "introiit autem Isaias propheta ad regem Ezechiam et dixit ei quid dixerunt viri isti et unde venerunt ad te et dixit Ezechias de terra longinqua venerunt ad me de Babylone;", "brenton": "And Esaias the prophet came to king Ezekias, and said to him, What say these men? and whence came they to thee? and Ezekias said, They are come to me from a land afar off, from Babylon."}}, {"v": 4, "ref": "39:4", "o": "וַ/יֹּ֕אמֶר מָ֥ה רָא֖וּ בְּ/בֵיתֶ֑/ךָ וַ/יֹּ֣אמֶר חִזְקִיָּ֗הוּ אֵ֣ת כָּל אֲשֶׁ֤ר בְּ/בֵיתִ/י֙ רָא֔וּ לֹֽא הָיָ֥ה דָבָ֛ר אֲשֶׁ֥ר לֹֽא הִרְאִיתִ֖י/ם בְּ/אוֹצְרֹתָֽ/י", "en": {"kjv": "Then said he, What have they seen in thine house? And Hezekiah answered, All that is in mine house have they seen: there is nothing among my treasures that I have not shewed them.", "web": "Then he asked, “What have they seen in your house?” Hezekiah answered, “They have seen all that is in my house. There is nothing among my treasures that I have not shown them.”", "bsb": "“What have they seen in your palace?” Isaiah asked. “They have seen everything in my palace,” answered Hezekiah. “There is nothing among my treasures that I did not show them.”", "asv": "Then said he, What have they seen in thy house? And Hezekiah answered, All that is in my house have they seen: there is nothing among my treasures that I have not showed them.", "ylt": "And he saith, `What saw they in thy house?' and Hezekiah saith, `All that is in my house they saw; there hath not been a thing that I have not shewed them among my treasures.'", "dra": "And he said: What saw they in thy house? And Ezechias said: All things that are in my house have they seen, there was not any thing which I have not shewn them in my treasures.", "bbe": "And he said, What have they seen in your house? And Hezekiah said in answer, They saw everything in my house: there is nothing among my stores which I did not let them see.", "geneva": "Then saide he, What haue they seene in thine house? And Hezekiah answered, All that is in mine house haue they seene: there is nothing among my treasures, that I haue not shewed them.", "wycliffe": "And Ysaie seide, What siyen thei in thin hous? And Ezechie seide, Thei sien alle thingis that ben in myn hous; no thing was in my tresours, which Y schewide not to hem.", "rotherham": "And he said, What have they seen in thy house? Then said Hezekiah,—All that is in my house, have they seen, there is nothing which I shewed them not among my treasures.", "darby": "And he said, What have they seen in thy house? And Hezekiah said, All that is in my house have they seen: there is nothing among my treasures that I have not shewn them.", "twenty": "", "jps": "Then said he: 'What have they seen in thy house?' And Hezekiah answered: 'All that is in my house have they seen; there is nothing among my treasures that I have not shown them.'", "acv": "Then he said, What have they seen in thy house? And Hezekiah answered, They have seen all that is in my house. There is nothing among my treasures that I have not shown them.", "anderson": "", "haweis": "", "noyes": "Then said he, What have they seen in thy house? And Hezekiah answered: All that is in my house have they seen. There is nothing in my treasures which I have not shown them.", "webster": "Then said he, What have they seen in thy house? And Hezekiah answered, All that [is] in my house have they seen: there is nothing among my treasures that I have not showed them.", "vulgate": "et dixit quid viderunt in domo tua et dixit Ezechias omnia quae in domo mea sunt viderunt non fuit res quam non ostenderim eis in thesauris meis;", "brenton": "And Esaias said, What have they seen in thine house? and Ezekias said, They have seen everything in my house; and there is nothing in my house which they have not seen: yea, also the possessions in my treasuries."}}, {"v": 5, "ref": "39:5", "o": "וַ/יֹּ֥אמֶר יְשַׁעְיָ֖הוּ אֶל חִזְקִיָּ֑הוּ שְׁמַ֖ע דְּבַר יְהוָ֥ה צְבָאֽוֹת", "en": {"kjv": "Then said Isaiah to Hezekiah, Hear the word of the Lord of hosts:", "web": "Then Isaiah said to Hezekiah, “Hear the word of Yahweh of Armies:", "bsb": "Then Isaiah said to Hezekiah, “Hear the word of the LORD of Hosts:", "asv": "Then said Isaiah to Hezekiah, Hear the word of Jehovah of hosts:", "ylt": "And Isaiah saith unto Hezekiah, `Hear a word of Jehovah of Hosts:", "dra": "And Isaiah said to Ezechias: Hear the word of the Lord of hosts.", "bbe": "Then said Isaiah to Hezekiah, Give ear to the word of the Lord of armies:", "geneva": "And Isaiah saide to Hezekiah, Heare the worde of the Lord of hostes,", "wycliffe": "And Ysaie seide to Ezechie, Here thou the word of the Lord of oostis.", "rotherham": "Then said Isaiah unto Hezekiah,—Hear thou the word of Yahweh of hosts:", "darby": "And Isaiah said to Hezekiah, Hear the word of Jehovah of hosts:", "twenty": "", "jps": "Then said Isaiah to Hezekiah: 'Hear the word of HaShem of hosts:", "acv": "Then Isaiah said to Hezekiah, Hear the word of Jehovah of hosts:", "anderson": "", "haweis": "", "noyes": "Then said Isaiah to Hezekiah, hear the word of Jehovah of hosts,", "webster": "Then said Isaiah to Hezekiah, Hear the word of the LORD of hosts:", "vulgate": "et dixit Isaias ad Ezechiam audi verbum Domini exercituum;", "brenton": "And Esaias said to him, Hear the word of the Lord of hosts:"}}, {"v": 6, "ref": "39:6", "o": "הִנֵּה֮ יָמִ֣ים בָּאִים֒ וְ/נִשָּׂ֣א כָּל אֲשֶׁ֣ר בְּ/בֵיתֶ֗/ךָ וַ/אֲשֶׁ֨ר אָצְר֧וּ אֲבֹתֶ֛י/ךָ עַד הַ/יּ֥וֹם הַ/זֶּ֖ה בָּבֶ֑ל לֹֽא יִוָּתֵ֥ר דָּבָ֖ר אָמַ֥ר יְהוָֽה", "en": {"kjv": "Behold, the days come, that all that is in thine house, and that which thy fathers have laid up in store until this day, shall be carried to Babylon: nothing shall be left, saith the Lord.", "web": "‘Behold, the days are coming when all that is in your house, and that which your fathers have stored up until this day, will be carried to Babylon. Nothing will be left,’ says Yahweh.", "bsb": "The time will surely come when everything in your palace and all that your fathers have stored up until this day will be carried off to Babylon. Nothing will be left, says the LORD.", "asv": "Behold, the days are coming, when all that is in thy house, and that which thy fathers have laid up in store until this day, shall be carried to Babylon: nothing shall be left, saith Jehovah.", "ylt": "Lo, days are coming, and borne hath been all that is in thy house, and that thy fathers have treasured up till this day, to Babylon; there is not left a thing, said Jehovah;", "dra": "Behold the days shall come that all that is in thy house, and that thy fathers have laid up in store until this day, shall be carried away into Babylon: there shall not any thing be left, saith the Lord.", "bbe": "Truly, the days are coming when everything in your house, and whatever your fathers have put in store till this day, will be taken away to Babylon: all will be gone.", "geneva": "Beholde, the dayes come, that all that is in thine house, and which thy fathers haue layed vp in store vntill this day, shall be caried to Babel: nothing shall be left, sayeth the Lord.", "wycliffe": "Lo! daies schulen come, and alle thingis that ben in thin hous, and whiche thingis thi fadris tresoriden til to this dai, schulen be takun awei in to Babiloyne; not ony thing schal be left, seith the Lord.", "rotherham": "Lo! days are coming, when all that is in thy house, and that which thy fathers have treasured up until this day, shall be carried away unto Babylon,—nothing, shall be left, Saith Yahweh.", "darby": "Behold, days come when all that is in thy house, and that which thy fathers have laid up until this day, shall be carried to Babylon: nothing shall be left, saith Jehovah.", "twenty": "", "jps": "Behold, the days come, that all that is in thy house, and that which thy fathers have laid up in store until this day, shall be carried to Babylon; nothing shall be left, saith HaShem.", "acv": "Behold, the days are coming, when all that is in thy house, and that which thy fathers have laid up in store until this day, shall be carried to Babylon. Nothing shall be left, says Jehovah.", "anderson": "", "haweis": "", "noyes": "Behold, the days shall come, when all that is in thy house, and that thy fathers have treasured up to this day, shall be carried away to Babylon. Nothing shall be left, saith Jehovah.", "webster": "Behold, the days come, that all that [is] in thy house, and [that] which thy fathers have laid up in store until this day, shall be carried to Babylon: nothing shall be left, saith the LORD.", "vulgate": "ecce dies venient et auferentur omnia quae in domo tua sunt et quae thesaurizaverunt patres tui usque ad diem hanc in Babylonem non relinquetur quicquam dicit Dominus;", "brenton": "Behold, the days come, when they shall take all the things that are in thine house, and all that thy fathers have gathered until this day, shall go to Babylon; and they shall not leave anything at all: and God hath said,"}}, {"v": 7, "ref": "39:7", "o": "וּ/מִ/בָּנֶ֜י/ךָ אֲשֶׁ֨ר יֵצְא֧וּ מִמְּ/ךָ֛ אֲשֶׁ֥ר תּוֹלִ֖יד יִקָּ֑חוּ וְ/הָיוּ֙ סָרִיסִ֔ים בְּ/הֵיכַ֖ל מֶ֥לֶךְ בָּבֶֽל", "en": {"kjv": "And of thy sons that shall issue from thee, which thou shalt beget, shall they take away; and they shall be eunuchs in the palace of the king of Babylon.", "web": "‘They will take away your sons who will issue from you, whom you shall father, and they will be eunuchs in the king of Babylon’s palace.’”", "bsb": "And some of your descendants, your own flesh and blood, will be taken away to be eunuchs in the palace of the king of Babylon.”", "asv": "And of thy sons that shall issue from thee, whom thou shalt beget, shall they take away; and they shall be eunuchs in the palace of the king of Babylon.", "ylt": "and of thy sons who come forth from thee, whom thou begettest, they take, and they have been eunuchs in a palace of the king of Babylon.'", "dra": "And of thy children, that shall issue from thee, whom thou shalt beget, they shall take away, and they shall be eunuchs in the palace of the king of Babylon.", "bbe": "And your sons, even your offspring, will they take away to be unsexed servants in the house of the king of Babylon.", "geneva": "And of thy sonnes, that shall proceede out of thee, and which thou shalt beget, shall they take away, and they shall be eunuches in the palace of the King of Babel.", "wycliffe": "And thei schulen take of thi sones, that schulen go out of thee, whiche thou schalt gendre; and thei schulen be onest seruauntis and chast in the paleis of the kyng of Babiloyne.", "rotherham": "And of thy sons who shall issue from thee whom thou shalt beget, shall they take away,—and they shall become eunuchs in the palace of the king of Babylon.", "darby": "And of thy sons that shall issue from thee, whom thou shalt beget, shall they take away; and they shall be eunuchs in the palace of the king of Babylon.", "twenty": "", "jps": "And of thy sons that shall issue from thee, whom thou shalt beget, shall they take away; and they shall be officers in the palace of the king of Babylon.'", "acv": "And of thy sons who shall issue from thee, whom thou shall beget, they shall take away, and they shall be eunuchs in the palace of the king of Babylon.", "anderson": "", "haweis": "", "noyes": "And of thy sons, which shall issue from thee, which thou shalt beget, shall they take away, and they shall he eunuchs in the palace of the king of Babylon. Then said Hezekiah to Isaiah, Good is the word of Jehovah, which thou hast spoken. For, said he, there shall be peace and security in my days.", "webster": "And of thy sons that shall issue from thee, which thou shalt beget, shall they take away; and they shall be eunuchs in the palace of the king of Babylon.", "vulgate": "et de filiis tuis qui exibunt de te quos genueris tollent et erunt eunuchi in palatio regis Babylonis;", "brenton": "that they shall take also of thy children whom thou shalt beget; and they shall make them eunuchs in the house of the king of the Babylonians."}}, {"v": 8, "ref": "39:8", "o": "וַ/יֹּ֤אמֶר חִזְקִיָּ֨הוּ֙ אֶֽל יְשַׁעְיָ֔הוּ ט֥וֹב דְּבַר יְהוָ֖ה אֲשֶׁ֣ר דִּבַּ֑רְתָּ וַ/יֹּ֕אמֶר כִּ֥י יִהְיֶ֛ה שָׁל֥וֹם וֶ/אֱמֶ֖ת בְּ/יָמָֽ/י", "en": {"kjv": "Then said Hezekiah to Isaiah, Good is the word of the Lord which thou hast spoken. He said moreover, For there shall be peace and truth in my days.", "web": "Then Hezekiah said to Isaiah, “Yahweh’s word which you have spoken is good.” He said moreover, “For there will be peace and truth in my days.”", "bsb": "But Hezekiah said to Isaiah, “The word of the LORD that you have spoken is good.” For he thought, “At least there will be peace and security in my lifetime.”", "asv": "Then said Hezekiah unto Isaiah, Good is the word of Jehovah which thou hast spoken. He said moreover, For there shall be peace and truth in my days.", "ylt": "And Hezekiah saith unto Isaiah, `Good is the word of Jehovah that thou hast spoken;' and he saith, `Because there is peace and truth in my days.'", "dra": "And Ezechias said to Isaiah: The word of the Lord, which he hath spoken, is good. And he said: Only let peace and truth be in my days.", "bbe": "Then said Hezekiah to Isaiah, Good is the word of the Lord which you have said. And he said in his heart, There will be peace and quiet in my days.", "geneva": "Then said Hezekiah to Isaiah, The worde of the Lord is good, which thou hast spoken: and he saide, Yet let there be peace, and trueth in my dayes.", "wycliffe": "And Ezechie seide to Ysaie, The word of the Lord is good, which he spak. And Ezechie seide, Pees and treuthe be maad oneli in my daies.", "rotherham": "And Hezekiah said unto Isaiah, Good is the word of Yahweh, which thou hast spoken. And he said, Surely, there shall be peace and stability in my days.", "darby": "And Hezekiah said to Isaiah, Good is the word of Jehovah which thou hast spoken. And he said, For there shall be peace and truth in my days.", "twenty": "", "jps": "Then said Hezekiah unto Isaiah: 'Good is the word of HaShem which thou hast spoken.' He said moreover: 'If but there shall be peace and truth in my days.'", "acv": "Then Hezekiah said to Isaiah, The word of Jehovah which thou have spoken is good. He said moreover, For there shall be peace and truth in my days.", "anderson": "", "haweis": "", "noyes": "", "webster": "Then said Hezekiah to Isaiah, Good [is] the word of the LORD which thou hast spoken. He said moreover, For there shall be peace and truth in my days.", "vulgate": "et dixit Ezechias ad Isaiam bonum verbum Domini quod locutus est et dixit fiat tantum pax et veritas in diebus meis;", "brenton": "And Ezekias said to Esaias, Good is the word of the Lord, which he hath spoken: let there, I pray, be peace and righteousness in my days."}}]}, {"c": 40, "verses": [{"v": 1, "ref": "40:1", "o": "נַחֲמ֥וּ נַחֲמ֖וּ עַמִּ֑/י יֹאמַ֖ר אֱלֹהֵי/כֶֽם", "en": {"kjv": "Comfort ye, comfort ye my people, saith your God.", "web": "“Comfort, comfort my people,” says your God.", "bsb": "“Comfort, comfort My people,” says your God.", "asv": "Comfort ye, comfort ye my people, saith your God.", "ylt": "Comfort ye, comfort ye, My people, saith your God.", "dra": "Be comforted, be comforted, my people, saith your God.", "bbe": "Give comfort, give comfort, to my people, says your God.", "geneva": "Comfort ye, comfort ye my people, will your God say.", "wycliffe": "My puple, be ye coumfortid, be ye coumfortid, seith youre Lord God.", "rotherham": "Comfort ye—comfort ye my people,—Saith your God.", "darby": "Comfort ye, comfort ye my people, saith yourGod.", "twenty": "", "jps": "Comfort ye, comfort ye My people, saith your G-d.", "acv": "Comfort ye, comfort ye my people, says your God.", "anderson": "", "haweis": "", "noyes": "Comfort ye, comfort ye, my people, Saith your God.", "webster": "Comfort ye, comfort ye my people, saith your God.", "vulgate": "consolamini consolamini populus meus dicit Deus vester;", "brenton": "Comfort ye, comfort ye my people, saith God."}}, {"v": 2, "ref": "40:2", "o": "דַּבְּר֞וּ עַל לֵ֤ב יְרֽוּשָׁלִַ֨ם֙ וְ/קִרְא֣וּ אֵלֶ֔י/הָ כִּ֤י מָֽלְאָה֙ צְבָאָ֔/הּ כִּ֥י נִרְצָ֖ה עֲוֺנָ֑/הּ כִּ֤י לָקְחָה֙ מִ/יַּ֣ד יְהוָ֔ה כִּפְלַ֖יִם בְּ/כָל חַטֹּאתֶֽי/הָ", "en": {"kjv": "Speak ye comfortably to Jerusalem, and cry unto her, that her warfare is accomplished, that her iniquity is pardoned: for she hath received of the Lord’s hand double for all her sins.", "web": "“Speak comfortably to Jerusalem; and call out to her that her warfare is accomplished, that her iniquity is pardoned, that she has received of Yahweh’s hand double for all her sins.”", "bsb": "“Speak tenderly to Jerusalem, and proclaim to her that her forced labor has been completed; her iniquity has been pardoned. For she has received from the hand of the LORD double for all her sins.”", "asv": "Speak ye comfortably to Jerusalem; and cry unto her, that her warfare is accomplished, that her iniquity is pardoned, that she hath received of Jehovah’s hand double for all her sins.", "ylt": "Speak to the heart of Jerusalem, and call to her, That her warfare hath been completed, That accepted hath been her punishment, That she hath received from the hand of Jehovah Double for all her sins.", "dra": "Speak ye to the heart of Jerusalem, and call to her: for her evil is come to an end, her iniquity is forgiven: she hath received of the hand of the Lord double for all her sins.", "bbe": "Say kind words to the heart of Jerusalem, crying out to her that her time of trouble is ended, that her punishment is complete; that she has been rewarded by the Lord's hand twice over for all her sins.", "geneva": "Speake comfortably to Ierusalem, and crye vnto her, that her warrefare is accomplished, that her iniquitie is pardoned: for she hath receiued of the Lords hand double for all her sinnes.", "wycliffe": "Speke ye to the herte of Jerusalem, and clepe ye it, for the malice therof is fillid, the wickidnesse therof is foryouun; it hath resseyued of the hond of the Lord double thingis for alle hise synnes.", "rotherham": "Speak ye unto the heart of Jerusalem, And cry unto her,—That accomplished is her warfare, That accepted is her punishment,—That she hath received, at the hand of Yahweh, According to the full measure of all her sins.", "darby": "Speak to the heart of Jerusalem, and cry unto her, that her time of suffering is accomplished, that her iniquity is pardoned; for she hath received of Jehovah's hand double for all her sins.", "twenty": "", "jps": "Bid Jerusalem take heart, and proclaim unto her, that her time of service is accomplished, that her guilt is paid off; that she hath received of HaShem'S hand double for all her sins.", "acv": "Speak ye comfortably to Jerusalem, and cry to her, that her warfare has been completed, that her iniquity is pardoned, that she has received of Jehovah's hand double for all her sins.", "anderson": "", "haweis": "", "noyes": "Speak ye encouragement to Jerusalem, and declare to her, That her hard service is ended; That her iniquity is expiated; That she hath received from the hand of Jehovah Double for all her sins.", "webster": "Speak ye comfortably to Jerusalem, and cry to her, that her warfare is accomplished, that her iniquity is pardoned: for she hath received from the LORD'S hand double for all her sins.", "vulgate": "loquimini ad cor Hierusalem et avocate eam quoniam conpleta est malitia eius dimissa est iniquitas illius suscepit de manu Domini duplicia pro omnibus peccatis suis;", "brenton": "Speak, ye priests, to the heart of Jerusalem; comfort her, for her humiliation is accomplished, her sin is put away: for she has received of the Lord's hand double the amount of her sins."}}, {"v": 3, "ref": "40:3", "o": "ק֣וֹל קוֹרֵ֔א בַּ/מִּדְבָּ֕ר פַּנּ֖וּ דֶּ֣רֶךְ יְהוָ֑ה יַשְּׁרוּ֙ בָּ/עֲרָבָ֔ה מְסִלָּ֖ה לֵ/אלֹהֵֽי/נוּ", "en": {"kjv": "The voice of him that crieth in the wilderness, Prepare ye the way of the Lord, make straight in the desert a highway for our God.", "web": "The voice of one who calls out, “Prepare the way of Yahweh in the wilderness! Make a level highway in the desert for our God.", "bsb": "A voice of one calling: “Prepare the way for the LORD in the wilderness; make a straight highway for our God in the desert.", "asv": "The voice of one that crieth, Prepare ye in the wilderness the way of Jehovah; make level in the desert a highway for our God.", "ylt": "A voice is crying--in a wilderness--Prepare ye the way of Jehovah, Make straight in a desert a highway to our God.", "dra": "The voice of one crying in the desert: Prepare ye the way of the Lord, make straight in the wilderness the paths of our God.", "bbe": "A voice of one crying, Make ready in the waste land the way of the Lord, make level in the lowland a highway for our God.", "geneva": "A voyce cryeth in the wildernesse, Prepare ye the way of the Lord: make streight in the desert a path for our God.", "wycliffe": "The vois of a crier in desert, Make ye redi the weie of the Lord, make ye riytful the pathis of oure God in wildirnesse.", "rotherham": "A voice of one crying!—In the desert, prepare ye the way of Yahweh,—Make smooth in the waste plain a highway for our God:", "darby": "The voice of one crying in the wilderness: Prepare ye the way of Jehovah, make straight in the desert a highway for ourGod!", "twenty": "", "jps": "Hark! one calleth: 'Clear ye in the wilderness the way of HaShem, make plain in the desert a highway for our G-d.", "acv": "The voice of a man crying out in the wilderness, Prepare ye the way of Jehovah, make straight in the desert a highway for our God.", "anderson": "", "haweis": "", "noyes": "A voice crieth: \"Prepare ye in the wilderness the way of Jehovah; Make straight in the desert a highway for our God!", "webster": "The voice of him that crieth in the wilderness, Prepare ye the way of the LORD, make straight in the desert a highway for our God.", "vulgate": "vox clamantis in deserto parate viam Domini rectas facite in solitudine semitas Dei nostri;", "brenton": "The voice of one crying in the wilderness, Prepare ye the way of the Lord, make straight the paths of our God."}}, {"v": 4, "ref": "40:4", "o": "כָּל גֶּיא֙ יִנָּשֵׂ֔א וְ/כָל הַ֥ר וְ/גִבְעָ֖ה יִשְׁפָּ֑לוּ וְ/הָיָ֤ה הֶֽ/עָקֹב֙ לְ/מִישׁ֔וֹר וְ/הָ/רְכָסִ֖ים לְ/בִקְעָֽה", "en": {"kjv": "Every valley shall be exalted, and every mountain and hill shall be made low: and the crooked shall be made straight, and the rough places plain:", "web": "Every valley shall be exalted, and every mountain and hill shall be made low. The uneven shall be made level, and the rough places a plain.", "bsb": "Every valley shall be lifted up, and every mountain and hill made low; the uneven ground will become smooth, and the rugged land a plain.", "asv": "Every valley shall be exalted, and every mountain and hill shall be made low; and the uneven shall be made level, and the rough places a plain:", "ylt": "Every valley is raised up, And every mountain and hill become low, And the crooked place hath become a plain, And the entangled places a valley.", "dra": "Every valley shall be exalted, and every mountain and hill shall be made low, and the crooked shall become straight, and the rough ways plain.", "bbe": "Let every valley be lifted up, and every mountain and hill be made low, and let the rough places become level, and the hilltops become a valley,", "geneva": "Euery valley shall be exalted, and euery mountaine and hill shall be made lowe: and the crooked shalbe streight, and the rough places plaine.", "wycliffe": "Ech valey schal be enhaunsid, and ech mounteyn and litil hil schal be maad low; and schrewid thingis schulen be in to streiyt thingis, and scharpe thingis schulen be in to pleyn weies.", "rotherham": "Let, every valley, be exalted, And every mountain and hill, be made low,—And, the steep ground become, level, And, the chain of hills—a plain:", "darby": "Every valley shall be raised up, and every mountain and hill shall be brought low; and the crooked shall be made straight, and the rough places a plain.", "twenty": "", "jps": "Every valley shall be lifted up, and every mountain and hill shall be made low; and the rugged shall be made level, and the rough places a plain;", "acv": "Every valley shall be exalted, and every mountain and hill shall be made low. And the crooked shall become straight, and the rough places smooth.", "anderson": "", "haweis": "", "noyes": "Every valley shall be exalted, And every mountain and hill be made low; The crooked shall become straight, And the rough places plain.", "webster": "Every valley shall be exalted, and every mountain and hill shall be made low: and the crooked shall be made straight, and the rough places plain.", "vulgate": "omnis vallis exaltabitur et omnis mons et collis humiliabitur et erunt prava in directa et aspera in vias planas;", "brenton": "Every valley shall be filled, and every mountain and hill shall be brought low: and all the crooked ways shall become straight, and the rough places plains."}}, {"v": 5, "ref": "40:5", "o": "וְ/נִגְלָ֖ה כְּב֣וֹד יְהוָ֑ה וְ/רָא֤וּ כָל בָּשָׂר֙ יַחְדָּ֔ו כִּ֛י פִּ֥י יְהוָ֖ה דִּבֵּֽר", "en": {"kjv": "And the glory of the Lord shall be revealed, and all flesh shall see it together: for the mouth of the Lord hath spoken it.", "web": "Yahweh’s glory shall be revealed, and all flesh shall see it together; for the mouth of Yahweh has spoken it.”", "bsb": "And the glory of the LORD will be revealed, and all humanity together will see it. For the mouth of the LORD has spoken.”", "asv": "and the glory of Jehovah shall be revealed, and all flesh shall see it together; for the mouth of Jehovah hath spoken it.", "ylt": "And revealed hath been the honour of Jehovah, And seen it have all flesh together, For the mouth of Jehovah hath spoken.", "dra": "And the glory of the Lord shall be revealed, and all flesh together shall see, that the mouth of the Lord hath spoken.", "bbe": "And the glory of the Lord will be made clear, and all flesh will see it together, for the mouth of the Lord has said it.", "geneva": "And the glory of the Lord shalbe reueiled, and all flesh shall see it together: for the mouth of the Lord hath spoken it.", "wycliffe": "And the glorie of the Lord schal be schewid, and ech man schal se togidere, that the mouth of the Lord hath spoke.", "rotherham": "Then shall be revealed the glory of Yahweh,—And all flesh shall see it together, For, the mouth of Yahweh, hath spoken!", "darby": "And the glory of Jehovah shall be revealed, and all flesh shall see [it] together: for the mouth of Jehovah hath spoken.", "twenty": "", "jps": "And the glory of HaShem shall be revealed, and all flesh shall see it together; for the mouth of HaShem hath spoken it.'", "acv": "And the glory of Jehovah shall be revealed, and all flesh shall see it together. For the mouth of Jehovah has spoken it.", "anderson": "", "haweis": "", "noyes": "For the glory of Jehovah shall be revealed, And all flesh shall see it together; For the mouth of Jehovah hath spoken it!\"", "webster": "And the glory of the LORD shall be revealed, and all flesh together shall see [it]: for the mouth of the LORD hath spoken [it].", "vulgate": "et revelabitur gloria Domini et videbit omnis caro pariter quod os Domini locutum est;", "brenton": "And the glory of the Lord shall appear, and all flesh shall see the salvation of God: for the Lord has spoken it."}}, {"v": 6, "ref": "40:6", "o": "ק֚וֹל אֹמֵ֣ר קְרָ֔א וְ/אָמַ֖ר מָ֣ה אֶקְרָ֑א כָּל הַ/בָּשָׂ֣ר חָצִ֔יר וְ/כָל חַסְדּ֖/וֹ כְּ/צִ֥יץ הַ/שָּׂדֶֽה", "en": {"kjv": "The voice said, Cry. And he said, What shall I cry? All flesh is grass, and all the goodliness thereof is as the flower of the field:", "web": "The voice of one saying, “Cry!” One said, “What shall I cry?” “All flesh is like grass, and all its glory is like the flower of the field.", "bsb": "A voice says, “Cry out!” And I asked, “What should I cry out?” “All flesh is like grass, and all its glory like the flowers of the field.", "asv": "The voice of one saying, Cry. And one said, What shall I cry? All flesh is grass, and all the goodliness thereof is as the flower of the field.", "ylt": "A voice is saying, `Call,' And he said, `What do I call?' All flesh is grass, and all its goodliness is As a flower of the field:", "dra": "The voice of one, saying: Cry. And I said: What shall I cry? All flesh is grass, and all the glory thereof as the flower of the field.", "bbe": "A voice of one saying, Give a cry! And I said, What is my cry to be? All flesh is grass, and all its strength like the flower of the field.", "geneva": "A voyce saide, Crie. And he saide, What shall I crie? All flesh is grasse, and all the grace thereof is as the floure of the fielde.", "wycliffe": "The vois of God, seiynge, Crie thou. And Y seide, What schal Y crie? Ech fleisch is hei, and al the glorie therof is as the flour of the feeld.", "rotherham": "A voice saying Cry! And one said—What should I cry? All flesh, is grass, And, all the grace thereof, like the flower of the field:", "darby": "A voice saith, Cry. And he saith, What shall I cry? — All flesh is grass, and all the comeliness thereof as the flower of the field.", "twenty": "", "jps": "Hark! one saith: 'Proclaim!' And he saith: 'What shall I proclaim?' 'All flesh is grass, and all the goodliness thereof is as the flower of the field;", "acv": "The voice said, Cry. And he said, What shall I cry? All flesh is grass, and all the goodliness of it is as the flower of the field.", "anderson": "", "haweis": "", "noyes": "A voice said, Proclaim! And I said, What shall I proclaim? All flesh is grass, And all its comeliness as the flower of the field.", "webster": "The voice said, Cry. And he said, What shall I cry? All flesh [is] grass, and all its goodliness [is] as the flower of the field:", "vulgate": "vox dicentis clama et dixi quid clamabo omnis caro faenum et omnis gloria eius quasi flos agri;", "brenton": "The voice of one saying, Cry; and I said, What shall I cry? All flesh is grass, and all the glory of man as the flower of grass:"}}, {"v": 7, "ref": "40:7", "o": "יָבֵ֤שׁ חָצִיר֙ נָ֣בֵֽל צִ֔יץ כִּ֛י ר֥וּחַ יְהוָ֖ה נָ֣שְׁבָה בּ֑/וֹ אָכֵ֥ן חָצִ֖יר הָ/עָֽם", "en": {"kjv": "The grass withereth, the flower fadeth: because the spirit of the Lord bloweth upon it: surely the people is grass.", "web": "The grass withers, the flower fades, because Yahweh’s breath blows on it. Surely the people are like grass.", "bsb": "The grass withers and the flowers fall when the breath of the LORD blows on them; indeed, the people are grass.", "asv": "The grass withereth, the flower fadeth, because the breath of Jehovah bloweth upon it; surely the people is grass.", "ylt": "Withered hath grass, faded the flower, For the Spirit of Jehovah blew upon it, Surely the people is grass;", "dra": "The grass is withered, and the flower is fallen, because the spirit of the Lord hath blown upon it. Indeed the people is grass:", "bbe": "The grass becomes dry, the flower is dead; because the breath of the Lord goes over it: truly the people is grass.", "geneva": "The grasse withereth, the floure fadeth, because the Spirite of the Lord bloweth vpon it: surely the people is grasse.", "wycliffe": "The hei is dried vp, and the flour felle doun, for the spirit of the Lord bleew therynne.", "rotherham": "The grass hath withered The flower hath faded, Because, the breath of Yahweh, hath blown upon it! Surely the people is grass!", "darby": "The grass withereth, the flower fadeth, for the breath of Jehovah bloweth upon it: surely the people is grass.", "twenty": "", "jps": "The grass withereth, the flower fadeth; because the breath of HaShem bloweth upon it--surely the people is grass.", "acv": "The grass withers, the flower fades, because the breath of Jehovah blows upon it. Surely the people is grass.", "anderson": "", "haweis": "", "noyes": "The grass withereth, the flower fadeth, When the breath of Jehovah bloweth upon it. Truly the people is grass.", "webster": "The grass withereth, the flower fadeth: because the spirit of the LORD bloweth upon it: surely the people [is] grass.", "vulgate": "exsiccatum est faenum et cecidit flos quia spiritus Domini sufflavit in eo vere faenum est populus;", "brenton": ""}}, {"v": 8, "ref": "40:8", "o": "יָבֵ֥שׁ חָצִ֖יר נָ֣בֵֽל צִ֑יץ וּ/דְבַר אֱלֹהֵ֖י/נוּ יָק֥וּם לְ/עוֹלָֽם", "en": {"kjv": "The grass withereth, the flower fadeth: but the word of our God shall stand for ever.", "web": "The grass withers, the flower fades; but the word of our God stands forever.”", "bsb": "The grass withers and the flowers fall, but the word of our God stands forever.”", "asv": "The grass withereth, the flower fadeth; but the word of our God shall stand forever.", "ylt": "Withered hath grass, faded the flower, But a word of our God riseth for ever.", "dra": "The grass is withered, and the flower is fallen: but the word of our Lord endureth for ever.", "bbe": "The grass is dry, the flower is dead; but the word of our God is eternal.", "geneva": "The grasse withereth, the floure fadeth: but the worde of our God shall stand for euer.", "wycliffe": "Verely the puple is hey; the hey is dried vp, and the flour felle doun; but the word of the Lord dwellith with outen ende.", "rotherham": "The grass, hath withered, The flower, hath faded,—But the word of our God, shall stand unto times age-abiding!", "darby": "The grass withereth, the flower fadeth; but the word of ourGod abideth for ever.", "twenty": "", "jps": "The grass withereth, the flower fadeth; but the word of our G-d shall stand for ever.'", "acv": "The grass withers, the flower fades, but the word of our God shall stand forever.", "anderson": "", "haweis": "", "noyes": "The grass withereth, the flower fadeth, But the word of our God shall stand forever.", "webster": "The grass withereth, the flower fadeth: but the word of our God shall shall stand forever.", "vulgate": "exsiccatum est faenum cecidit flos verbum autem Dei nostri stabit in aeternum;", "brenton": "The grass withers, and the flower fades: but the word of our God abides for ever."}}, {"v": 9, "ref": "40:9", "o": "עַ֣ל הַר גָּבֹ֤הַ עֲלִי לָ/ךְ֙ מְבַשֶּׂ֣רֶת צִיּ֔וֹן הָרִ֤ימִי בַ/כֹּ֨חַ֙ קוֹלֵ֔/ךְ מְבַשֶּׂ֖רֶת יְרוּשָׁלִָ֑ם הָרִ֨ימִי֙ אַל תִּירָ֔אִי אִמְרִי֙ לְ/עָרֵ֣י יְהוּדָ֔ה הִנֵּ֖ה אֱלֹהֵי/כֶֽם", "en": {"kjv": "O Zion, that bringest good tidings, get thee up into the high mountain; O Jerusalem, that bringest good tidings, lift up thy voice with strength; lift it up, be not afraid; say unto the cities of Judah, Behold your God!", "web": "You who tell good news to Zion, go up on a high mountain. You who tell good news to Jerusalem, lift up your voice with strength. Lift it up. Don’t be afraid. Say to the cities of Judah, “Behold, your God!”", "bsb": "Go up on a high mountain, O Zion, herald of good news. Raise your voice loudly, O Jerusalem, herald of good news. Lift it up, do not be afraid! Say to the cities of Judah, “Here is your God!”", "asv": "O thou that tellest good tidings to Zion, get thee up on a high mountain; O thou that tellest good tidings to Jerusalem, lift up thy voice with strength; lift it up, be not afraid; say unto the cities of Judah, Behold, your God!", "ylt": "On a high mountain get thee up, O Zion, Proclaiming tidings, Lift up with power thy voice, O Jerusalem, proclaiming tidings, Lift up, fear not, say to cities of Judah, `Lo, your God.'", "dra": "Get thee up upon a high mountain, thou that bringest good tidings to Sion: lift up thy voice with strength, thou that bringest good tidings to Jerusalem: lift it up, fear not. Say to the cities of Juda: Behold your God:", "bbe": "You who give good news to Zion, get up into the high mountain; you who give good news to Jerusalem, let your voice be strong; let it be sounding without fear; say to the towns of Judah, See, your God!", "geneva": "O Zion, that bringest good tidings, get thee vp into the hie mountaine: O Ierusalem, that bringest good tidings, lift vp thy voyce with strength: lift it vp, be not afraide: say vnto the cities of Iudah, Beholde your God.", "wycliffe": "Thou that prechist to Sion, stie on an hiy hil; thou that prechist to Jerusalem, enhaunse thi vois in strengthe; enhaunse thou, nyle thou drede; seie thou to the citees of Juda, Lo! youre God.", "rotherham": "To a high mountain, get ye up, O herald—band of Zion, Lift high with strength your voice, O herald—band of Jerusalem,—Lift it high, do not fear, Say to the cities of Judah—Lo! your God!", "darby": "O Zion, that bringest glad tidings, get thee up into a high mountain; O Jerusalem, that bringest glad tidings, lift up thy voice with strength: lift it up, be not afraid; say unto the cities of Judah, Behold yourGod!", "twenty": "", "jps": "O thou that tellest good tidings to Zion, get thee up into the high mountain; O thou that tellest good tidings to Jerusalem, lift up thy voice with strength; lift it up, be not afraid; say unto the cities of Judah: 'Behold your G-d!'", "acv": "O thou who tell good news to Zion, get thee up on a high mountain. O thou who tell good news to Jerusalem, lift up thy voice with strength. Lift it up, be not afraid, say to the cities of Judah, Behold, your God!", "anderson": "", "haweis": "", "noyes": "Get thee up on the high mountain, O thou that bringest glad tidings to Zion; Lift up thy voice with strength, thou that bringest glad tidings to Jerusalem; Lift it up; be not afraid; Say to the cities of Judah, Behold your God!", "webster": "O Zion, that bringest good tidings, go up upon the high mountain: O Jerusalem, that bringest good tidings, lift up thy voice with strength; lift [it] up, be not afraid; say to the cities of Judah, Behold your God!", "vulgate": "super montem excelsum ascende tu quae evangelizas Sion exalta in fortitudine vocem tuam quae evangelizas Hierusalem exalta noli timere dic civitatibus Iudae ecce Deus vester;", "brenton": "O thou that bringest glad tidings to Zion, go up on the high mountain; lift up thy voice with strength, thou that bringest glad tidings to Jerusalem; lift it up, fear not; say unto the cities of Juda, Behold your God!"}}, {"v": 10, "ref": "40:10", "o": "הִנֵּ֨ה אֲדֹנָ֤/י יְהוִה֙ בְּ/חָזָ֣ק יָב֔וֹא וּ/זְרֹע֖/וֹ מֹ֣שְׁלָה ל֑/וֹ הִנֵּ֤ה שְׂכָר/וֹ֙ אִתּ֔/וֹ וּ/פְעֻלָּת֖/וֹ לְ/פָנָֽי/ו", "en": {"kjv": "Behold, the Lord God will come with strong hand, and his arm shall rule for him: behold, his reward is with him, and his work before him.", "web": "Behold, the Lord Yahweh will come as a mighty one, and his arm will rule for him. Behold, his reward is with him, and his recompense before him.", "bsb": "Behold, the Lord GOD comes with might, and His arm establishes His rule. His reward is with Him, and His recompense accompanies Him.", "asv": "Behold, the Lord Jehovah will come as a mighty one, and his arm will rule for him: Behold, his reward is with him, and his recompense before him.", "ylt": "Lo, the Lord Jehovah with strength cometh, And His arm is ruling for Him, Lo, His hire is with Him, and His wage before Him.", "dra": "Behold the Lord God shall come with strength, and his arm shall rule: Behold his reward is with him and his work is before him.", "bbe": "See, the Lord God will come as a strong one, ruling in power: see, those made free by him are with him, and those whom he has made safe go before him.", "geneva": "Beholde, the Lord God will come with power, and his arme shall rule for him: beholde, his rewarde is with him, and his worke before him,", "wycliffe": "Lo! the Lord God schal come in strengthe, and his arm schal holde lordschipe; lo! his mede is with hym, and his werk is bifore hym.", "rotherham": "Lo! My Lord, Yahweh, as a mighty one, doth come, And, his own arm, is about to rule for him,—Lo! his reward, is with him, And, his recompense, before him;", "darby": "Behold, the Lord Jehovah will come with might, and his arm shall rule for him; behold, his reward is with him, and his recompence before him.", "twenty": "", "jps": "Behold, the L-rd GOD will come as a Mighty One, and His arm will rule for Him; behold, His reward is with Him, and His recompense before Him.", "acv": "Behold, the lord Jehovah will come as a mighty one, and his arm will rule for him. Behold, his reward is with him, and his recompense before him.", "anderson": "", "haweis": "", "noyes": "Behold, the Lord Jehovah shall come with might, And his arm shall rule for him; Behold, his reward is with him, And his recompense before him.", "webster": "Behold, the Lord GOD will come with strong [hand], and his arm will rule for him: behold, his reward [is] with him, and his work before him.", "vulgate": "ecce Dominus Deus in fortitudine veniet et brachium eius dominabitur ecce merces eius cum eo et opus illius coram eo;", "brenton": "Behold the Lord! The Lord is coming with strength, and his arm is with power: behold, his reward is with him, and his work before him."}}, {"v": 11, "ref": "40:11", "o": "כְּ/רֹעֶה֙ עֶדְר֣/וֹ יִרְעֶ֔ה בִּ/זְרֹע/וֹ֙ יְקַבֵּ֣ץ טְלָאִ֔ים וּ/בְ/חֵיק֖/וֹ יִשָּׂ֑א עָל֖וֹת יְנַהֵֽל", "en": {"kjv": "He shall feed his flock like a shepherd: he shall gather the lambs with his arm, and carry them in his bosom, and shall gently lead those that are with young.", "web": "He will feed his flock like a shepherd. He will gather the lambs in his arm, and carry them in his bosom. He will gently lead those who have their young.", "bsb": "He tends His flock like a shepherd; He gathers the lambs in His arms and carries them close to His heart. He gently leads the nursing ewes.", "asv": "He will feed his flock like a shepherd, he will gather the lambs in his arm, and carry them in his bosom, and will gently lead those that have their young.", "ylt": "As a shepherd His flock He feedeth, With His arm He gathereth lambs, And in His bosom He carrieth them : Suckling ones He leadeth.", "dra": "He shall feed his flock like a shepherd: he shall gather together the lambs with his arm, and shall take them up in his bosom, and he himself shall carry them that are with young.", "bbe": "He will give food to his flock like a keeper of sheep; with his arm he will get it together, and will take up the lambs on his breast, gently guiding those which are with young.", "geneva": "He shall feede his flocke like a shepheard: he shall gather the lambes with his arme, and cary them in his bosome, and shall guide them with young.", "wycliffe": "As a scheepherd he schal fede his flok, he schal gadere lambreen in his arm, and he schal reise in his bosom; he schal bere scheep `with lomb.", "rotherham": "Like a shepherd, his flock, will he tend, In his own arm, will he take up the lambs, And in his own bosom, will he carry [them],—Them which are with young, will he lead to a place of rest.", "darby": "He will feed his flock like a shepherd: he will gather the lambs with his arm, and carry them in his bosom; he will gently lead those that give suck.", "twenty": "", "jps": "Even as a shepherd that feedeth his flock, that gathereth the lambs in his arm, and carrieth them in his bosom, and gently leadeth those that give suck.", "acv": "He will feed his flock like a shepherd. He will gather the lambs in his arm, and carry them in his bosom, and will gently lead those who have their young.", "anderson": "", "haweis": "", "noyes": "He shall feed his flock like a shepherd; He shall gather up the lambs in his arms, And carry them in his bosom, And gently lead the nursing ewes.", "webster": "He will feed his flock like a shepherd: he will gather the lambs with his arm, and carry [them] in his bosom, [and] will gently lead those that are with young.", "vulgate": "sicut pastor gregem suum pascet in brachio suo congregabit agnos et in sinu suo levabit fetas ipse portabit;", "brenton": "He shall tend his flock as a shepherd, and he shall gather the lambs with his arm, and shall soothe them that are with young."}}, {"v": 12, "ref": "40:12", "o": "מִֽי מָדַ֨ד בְּ/שָׁעֳל֜/וֹ מַ֗יִם וְ/שָׁמַ֨יִם֙ בַּ/זֶּ֣רֶת תִּכֵּ֔ן וְ/כָ֥ל בַּ/שָּׁלִ֖שׁ עֲפַ֣ר הָ/אָ֑רֶץ וְ/שָׁקַ֤ל בַּ/פֶּ֨לֶס֙ הָרִ֔ים וּ/גְבָע֖וֹת בְּ/מֹאזְנָֽיִם", "en": {"kjv": "Who hath measured the waters in the hollow of his hand, and meted out heaven with the span, and comprehended the dust of the earth in a measure, and weighed the mountains in scales, and the hills in a balance?", "web": "Who has measured the waters in the hollow of his hand, and marked off the sky with his span, and calculated the dust of the earth in a measure, and weighed the mountains in scales, and the hills in a balance?", "bsb": "Who has measured the waters in the hollow of his hand, or marked off the heavens with the span of his hand? Who has held the dust of the earth in a basket, or weighed the mountains on a scale and the hills with a balance?", "asv": "Who hath measured the waters in the hollow of his hand, and meted out heaven with the span, and comprehended the dust of the earth in a measure, and weighed the mountains in scales, and the hills in a balance?", "ylt": "Who hath measured in the hollow of his hand the waters? And the heavens by a span hath meted out, And comprehended in a measure the dust of the earth, And hath weighed in scales the mountains, And the hills in a balance?", "dra": "Who hath measured the waters in the hollow of his hand, and weighed the heavens with his palm? who hath poised with three fingers the bulk of the earth, and weighed the mountains in scales, and the hills in a balance?", "bbe": "In the hollow of whose hand have the waters been measured? and who is able to take the heavens in his stretched-out fingers? who has got together the dust of the earth in a measure? who has taken the weight of the mountains, or put the hills into the scales?", "geneva": "Who hath measured the waters in his fist? and counted heauen with the spanne, and comprehended the dust of the earth in a measure? and weighed ye mountaines in a weight, and the hilles in a balance?", "wycliffe": "Who mat watris in a fist, and peiside heuenes with a spanne? Who peiside the heuynesse of the erthe with thre fyngris, and weide mounteyns in a weihe, and litle hillis in a balaunce?", "rotherham": "Who hath measured, with the hollow of his hand, the waters. Or the heavens with a span, hath meted out, Or hath comprehended, in a measure, the dust of the earth, Or weighed, in scales, the mountains, Or the hills, in a balance?", "darby": "Who hath measured the waters in the hollow of his hand, and meted out the heavens with [his] span, and grasped the dust of the earth in a measure, and weighed the mountains in a balance, and the hills in scales?", "twenty": "", "jps": "Who hath measured the waters in the hollow of his hand, and meted out heaven with the span, and comprehended the dust of the earth in a measure, and weighed the mountains in scales, and the hills in a balance?", "acv": "Who has measured the waters in the hollow of his hand, and meted out heaven with the span, and comprehended the dust of the earth in a measure, and weighed the mountains in scales, and the hills in a balance?", "anderson": "", "haweis": "", "noyes": "Who hath measured the waters in the hollow of his hand, And meted out the heavens with his span, And gathered the dust of the earth into a measure, And weighed the mountains in scales, And the hills in a balance?", "webster": "Who hath measured the waters in the hollow of his hand, and measured heaven with the span, and comprehended the dust of the earth in a measure, and weighed the mountains in scales, and the hills in a balance?", "vulgate": "quis mensus est pugillo aquas et caelos palmo ponderavit quis adpendit tribus digitis molem terrae et libravit in pondere montes et colles in statera;", "brenton": "Who has measured the water in his hand, and the heaven with a span, and all the earth in a handful? Who has weighed the mountains in scales, and the forests in a balance?"}}, {"v": 13, "ref": "40:13", "o": "מִֽי תִכֵּ֥ן אֶת ר֖וּחַ יְהוָ֑ה וְ/אִ֥ישׁ עֲצָת֖/וֹ יוֹדִיעֶֽ/נּוּ", "en": {"kjv": "Who hath directed the Spirit of the Lord, or being his counsellor hath taught him?", "web": "Who has directed the Spirit of Yahweh, or has taught him as his counselor?", "bsb": "Who has directed the Spirit of the LORD, or informed Him as His counselor?", "asv": "Who hath directed the Spirit of Jehovah, or being his counsellor hath taught him?", "ylt": "Who hath meted out the Spirit of Jehovah, And, being His counsellor, doth teach Him!", "dra": "Who hath forwarded the spirit of the Lord? or who hath been his counsellor, and hath taught him?", "bbe": "By whom has the spirit of the Lord been guided, or who has been his teacher?", "geneva": "Who hath instructed ye Spirit of the Lord? or was his counseler or taught him?", "wycliffe": "Who helpide the Spirit of the Lord, ether who was his councelour, and schewide to hym?", "rotherham": "Who hath proved the spirit of Yahweh? Or being his counsellor hath been giving him knowledge?", "darby": "Who hath directed the Spirit of Jehovah, and, [as] his counsellor, hath taught him?", "twenty": "", "jps": "Who hath meted out the spirit of HaShem? Or who was His counsellor that he might instruct Him?", "acv": "Who has known the mind of Jehovah, or being his counselor has taught him?", "anderson": "", "haweis": "", "noyes": "Who hath searched out the spirit of Jehovah, Or, being his counsellor, hath taught him?", "webster": "Who hath directed the Spirit of the LORD, or [being] his counselor hath taught him?", "vulgate": "quis adiuvit spiritum Domini aut quis consiliarius eius fuit et ostendit illi;", "brenton": "Who has known the mind of the Lord? and who has been his counsellor, to instruct him?"}}, {"v": 14, "ref": "40:14", "o": "אֶת מִ֤י נוֹעָץ֙ וַ/יְבִינֵ֔/הוּ וַֽ/יְלַמְּדֵ֖/הוּ בְּ/אֹ֣רַח מִשְׁפָּ֑ט וַ/יְלַמְּדֵ֣/הוּ דַ֔עַת וְ/דֶ֥רֶךְ תְּבוּנ֖וֹת יוֹדִיעֶֽ/נּוּ", "en": {"kjv": "With whom took he counsel, and who instructed him, and taught him in the path of judgment, and taught him knowledge, and shewed to him the way of understanding?", "web": "Who did he take counsel with, and who instructed him, and taught him in the path of justice, and taught him knowledge, and showed him the way of understanding?", "bsb": "Whom did He consult to enlighten Him, and who taught Him the paths of justice? Who imparted knowledge to Him and showed Him the way of understanding?", "asv": "With whom took he counsel, and who instructed him, and taught him in the path of justice, and taught him knowledge, and showed to him the way of understanding?", "ylt": "With whom consulted He, That he causeth Him to understand? And teacheth Him in the path of judgment, And teacheth Him knowledge? And the way of understanding causeth Him to know?", "dra": "With whom hath he consulted, and who hath instructed him, and taught him the path of justice, and taught him knowledge, and shewed him the way of understanding?", "bbe": "Who gave him suggestions, and made clear to him the right way? who gave him knowledge, guiding him in the way of wisdom?", "geneva": "Of whom tooke he counsell, and who instructed him and taught him in the way of iudgement? or taught him knowledge, and shewed vnto him the way of vnderstanding?", "wycliffe": "With whom took he councel, and who lernyde hym, and tauyte hym the path of riytfulnesse, and lernyde hym in kunnyng, and schewyde to him the weie of prudence?", "rotherham": "With whom hath he taken counsel—And he hath given him intelligence, And instructed him in the path of justice,—And taught him knowledge, And in the way of intelligence, hath been giving him understanding?", "darby": "With whom took he counsel, and [who] gave him intelligence, and instructed him in the path of judgment, and taught him knowledge, and shewed him the way of understanding?", "twenty": "", "jps": "With whom took He counsel, and who instructed Him, and taught Him in the path of right, and taught Him knowledge, and made Him to know the way of discernment?", "acv": "With whom did he take counsel. And who instructed him, and taught him in the path of justice. And taught him knowledge, and showed to him the way of understanding?", "anderson": "", "haweis": "", "noyes": "With whom took he counsel, and who instructed him, And taught him the path of justice, And taught him knowledge, And showed him the way of understanding?", "webster": "With whom took he counsel, and [who] instructed him, and taught him in the path of judgment, and taught him knowledge, and showed to him the way of understanding?", "vulgate": "cum quo iniit consilium et instruxit eum et docuit eum semitam iustitiae et erudivit eum scientiam et viam prudentiae ostendit illi;", "brenton": "Or with whom has he taken counsel, and he has instructed him? or who has taught him judgment, or who has taught him the way of understanding;"}}, {"v": 15, "ref": "40:15", "o": "הֵ֤ן גּוֹיִם֙ כְּ/מַ֣ר מִ/דְּלִ֔י וּ/כְ/שַׁ֥חַק מֹאזְנַ֖יִם נֶחְשָׁ֑בוּ הֵ֥ן אִיִּ֖ים כַּ/דַּ֥ק יִטּֽוֹל", "en": {"kjv": "Behold, the nations are as a drop of a bucket, and are counted as the small dust of the balance: behold, he taketh up the isles as a very little thing.", "web": "Behold, the nations are like a drop in a bucket, and are regarded as a speck of dust on a balance. Behold, he lifts up the islands like a very little thing.", "bsb": "Surely the nations are like a drop in a bucket; they are considered a speck of dust on the scales; He lifts up the islands like fine dust.", "asv": "Behold, the nations are as a drop of a bucket, and are accounted as the small dust of the balance: behold, he taketh up the isles as a very little thing.", "ylt": "Lo, nations as a drop from a bucket, And as small dust of the balance, have been reckoned, Lo, isles as a small thing He taketh up.", "dra": "Behold the Gentiles are as a drop of a bucket, and are counted as the smallest grain of a balance: behold the islands are as a little dust.", "bbe": "See, the nations are to him like a drop hanging from a bucket, and like the small dust in the scales: he takes up the islands like small dust.", "geneva": "Beholde, the nations are as a drop of a bucket, and are counted as the dust of the balance: beholde, he taketh away the yles as a litle dust.", "wycliffe": "Lo! folkis ben as a drope of a boket, and ben arettid as the tunge of a balaunce; lo!", "rotherham": "Lo! nations, Are us a drop on a bucket, And as fine dust on a balance, are accounted,—Lo! islands, like an atom, can he hoist;", "darby": "Behold, the nations are esteemed as a drop of the bucket, and as the fine dust on the scales; behold, he taketh up the isles as an atom.", "twenty": "", "jps": "Behold, the nations are as a drop of a bucket, and are counted as the small dust of the balance; behold the isles are as a mote in weight.", "acv": "Behold, the nations are as a drop of a bucket, and are accounted as the small dust of the balance. Behold, he takes up the isles as a very little thing.", "anderson": "", "haweis": "", "noyes": "Behold, the nations are as a drop from a bucket, And are accounted as the small dust of the balance; Behold, he taketh up the isles as a very little thing,", "webster": "Behold, the nations [are] as a drop of a bucket, and are counted as the small dust of the balance: behold, he taketh up the isles as a very little thing.", "vulgate": "ecce gentes quasi stilla situlae et quasi momentum staterae reputatae sunt ecce insulae quasi pulvis exiguus;", "brenton": "since all the nations are counted as a drop from a bucket, and as the turning of a balance, and shall be counted as spittle?"}}, {"v": 16, "ref": "40:16", "o": "וּ/לְבָנ֕וֹן אֵ֥ין דֵּ֖י בָּעֵ֑ר וְ/חַיָּת֔/וֹ אֵ֥ין דֵּ֖י עוֹלָֽה", "en": {"kjv": "And Lebanon is not sufficient to burn, nor the beasts thereof sufficient for a burnt offering.", "web": "Lebanon is not sufficient to burn, nor its animals sufficient for a burnt offering.", "bsb": "Lebanon is not sufficient for fuel, nor its animals enough for a burnt offering.", "asv": "And Lebanon is not sufficient to burn, nor the beasts thereof sufficient for a burnt-offering.", "ylt": "And Lebanon is not sufficient to burn, Nor its beasts sufficient for a burnt-offering.", "dra": "And Libanus shall not be enough to burn, nor the beasts thereof sufficient for a burnt offering.", "bbe": "And Lebanon is not enough to make a fire with, or all its cattle enough for a burned offering.", "geneva": "And Lebanon is not sufficient for fire, nor the beastes thereof sufficient for a burnt offering.", "wycliffe": "ylis ben as a litil dust, and the Liban schal not suffice to brenne his sacrifice, and the beestis therof schulen not suffice to brent sacrifice.", "rotherham": "And, Lebanon, is not sufficient to burn,—Nor, the beasts thereof sufficient for an ascending-sacrifice!", "darby": "And Lebanon is not sufficient to burn, nor the beasts thereof sufficient for a burnt-offering.", "twenty": "", "jps": "And Lebanon is not sufficient fuel, nor the beasts thereof sufficient for burnt-offerings.", "acv": "And Lebanon is not sufficient to burn, nor the beasts of it sufficient for a burnt offering.", "anderson": "", "haweis": "", "noyes": "And Lebanon is not sufficient for fire, Nor its beasts for a burnt-offering.", "webster": "And Lebanon [is] not sufficient to burn, nor the beasts of it sufficient for a burnt-offering.", "vulgate": "et Libanus non sufficiet ad succendendum et animalia eius non sufficient ad holocaustum;", "brenton": "And Libanus is not enough to burn, nor all beasts enough for a whole-burnt offering:"}}, {"v": 17, "ref": "40:17", "o": "כָּל הַ/גּוֹיִ֖ם כְּ/אַ֣יִן נֶגְדּ֑/וֹ מֵ/אֶ֥פֶס וָ/תֹ֖הוּ נֶחְשְׁבוּ לֽ/וֹ", "en": {"kjv": "All nations before him are as nothing; and they are counted to him less than nothing, and vanity.", "web": "All the nations are like nothing before him. They are regarded by him as less than nothing, and vanity.", "bsb": "All the nations are as nothing before Him; He regards them as nothingness and emptiness.", "asv": "All the nations are as nothing before him; they are accounted by him as less than nothing, and vanity.", "ylt": "All the nations are as nothing before Him, Less than nothing and emptiness, They have been reckoned to Him.", "dra": "All nations are before him as if they had no being at all, and are counted to him as nothing, and vanity.", "bbe": "All the nations are as nothing before him; even less than nothing, a thing of no value.", "geneva": "All nations before him are as nothing, and they are counted to him, lesse then nothing, and vanitie.", "wycliffe": "Alle folkis ben so bifore hym, as if thei ben not; and thei ben rettid as no thing and veyn thing to hym.", "rotherham": "All nations, are as nothing before him,—A thing of nought or a waste, are they accounted unto him?", "darby": "All the nations are as nothing before him; they are esteemed by him less than a cipher, and vanity.", "twenty": "", "jps": "All the nations are as nothing before Him; they are accounted by Him as things of nought, and vanity.", "acv": "All the nations are as nothing before him. They are accounted by him as less than nothing, and vanity.", "anderson": "", "haweis": "", "noyes": "All the nations are as nothing before him; They are accounted by him as less than nothing, and vanity.", "webster": "All nations before him [are] as nothing; and they are counted to him less than nothing, and vanity.", "vulgate": "omnes gentes quasi non sint sic sunt coram eo et quasi nihilum et inane reputatae sunt ei;", "brenton": "and all the nations are as nothing, and counted as nothing."}}, {"v": 18, "ref": "40:18", "o": "וְ/אֶל מִ֖י תְּדַמְּי֣וּ/ן אֵ֑ל וּ/מַה דְּמ֖וּת תַּ֥עַרְכוּ לֽ/וֹ", "en": {"kjv": "To whom then will ye liken God? or what likeness will ye compare unto him?", "web": "To whom then will you liken God? Or what likeness will you compare to him?", "bsb": "To whom will you liken God? To what image will you compare Him?", "asv": "To whom then will ye liken God? or what likeness will ye compare unto him?", "ylt": "And unto whom do ye liken God, And what likeness do ye compare to Him?", "dra": "To whom then have you likened God? or what image will you make for him?", "bbe": "Whom then is God like, in your opinion? or what will you put forward as a comparison with him?", "geneva": "To whom then wil ye liken God? or what similitude will ye set vp vnto him?", "wycliffe": "To whom therfor maden ye God lijk? ether what ymage schulen ye sette to hym?", "rotherham": "Unto whom then can ye liken GOD? Or, what likeness, can ye compare unto him?", "darby": "To whom then will ye likenGod? and what likeness will ye compare unto him?", "twenty": "", "jps": "To whom then will ye liken G-d? Or what likeness will ye compare unto Him?", "acv": "To whom then will ye liken God? Or what likeness will ye compare to him?", "anderson": "", "haweis": "", "noyes": "To whom then will ye liken God, And what likeness will ye compare unto him?", "webster": "To whom then will ye liken God? or what likeness will ye compare to him?", "vulgate": "cui ergo similem fecistis Deum aut quam imaginem ponetis ei;", "brenton": "To whom have ye compared the Lord? and with what likeness have ye compared him?"}}, {"v": 19, "ref": "40:19", "o": "הַ/פֶּ֨סֶל֙ נָסַ֣ךְ חָרָ֔שׁ וְ/צֹרֵ֖ף בַּ/זָּהָ֣ב יְרַקְּעֶ֑/נּוּ וּ/רְתֻק֥וֹת כֶּ֖סֶף צוֹרֵֽף", "en": {"kjv": "The workman melteth a graven image, and the goldsmith spreadeth it over with gold, and casteth silver chains.", "web": "A workman has cast an image, and the goldsmith overlays it with gold, and casts silver chains for it.", "bsb": "To an idol that a craftsman casts and a metalworker overlays with gold and fits with silver chains?", "asv": "The image, a workman hath cast it, and the goldsmith overlayeth it with gold, and casteth for it silver chains.", "ylt": "The graven image poured out hath a artisan, And a refiner with gold spreadeth it over, And chains of silver he is refining.", "dra": "Hath the workman cast a graven statue? or hath the goldsmith formed it with gold, or the silversmith with plates of silver?", "bbe": "The workman makes an image, and the gold-worker puts gold plates over it, and makes silver bands for it.", "geneva": "The workeman melteth an image, or the goldsmith beateth it out in golde, or the goldesmith maketh siluer plates.", "wycliffe": "Whether a smyth schal welle togidere an ymage, ether a gold smyth schal figure it in gold, and a worchere in siluer schal diyte it with platis of siluer?", "rotherham": "The image, hath been cast by an artificer, And a goldsmith, with gold, overlayeth it,—And, chains of silver, he worketh.", "darby": "The workman casteth a graven image, and the goldsmith spreadeth it over with gold, and casteth silver chains [for it].", "twenty": "", "jps": "The image perchance, which the craftsman hath melted, and the goldsmith spread over with gold, the silversmith casting silver chains?", "acv": "The image, a workman has cast it, and the goldsmith overlays it with gold, and casts for it silver chains.", "anderson": "", "haweis": "", "noyes": "The workman casteth an image, And the smith overlayeth it with gold, And casteth for it silver chains.", "webster": "The workman melteth a graven image, and the goldsmith spreadeth it over with gold, and casteth silver chains.", "vulgate": "numquid sculptile conflavit faber aut aurifex auro figuravit illud et lamminis argenteis argentarius;", "brenton": "Has not the artificer made an image, or the goldsmith having melted gold, gilt it over, and made it a similitude?"}}, {"v": 20, "ref": "40:20", "o": "הַֽ/מְסֻכָּ֣ן תְּרוּמָ֔ה עֵ֥ץ לֹֽא יִרְקַ֖ב יִבְחָ֑ר חָרָ֤שׁ חָכָם֙ יְבַקֶּשׁ ל֔/וֹ לְ/הָכִ֥ין פֶּ֖סֶל לֹ֥א יִמּֽוֹט", "en": {"kjv": "He that is so impoverished that he hath no oblation chooseth a tree that will not rot; he seeketh unto him a cunning workman to prepare a graven image, that shall not be moved.", "web": "He who is too impoverished for such an offering chooses a tree that will not rot. He seeks a skillful workman to set up an engraved image for him that will not be moved.", "bsb": "To one bereft of an offering who chooses wood that will not rot, who seeks a skilled craftsman to set up an idol that will not topple?", "asv": "He that is too impoverished for such an oblation chooseth a tree that will not rot; he seeketh unto him a skilful workman to set up a graven image, that shall not be moved.", "ylt": "He who is poor by heave-offerings, A tree not rotten doth choose, A skilful artisan he seeketh for it, To establish a graven image--not moved.", "dra": "He hath chosen strong wood, and that will not rot: the skilful workman seeketh how he may set up an idol that may not be moved.", "bbe": "The wise workman makes selection of the mulberry-tree of the offering, a wood which will not become soft; so that the image may be fixed to it and not be moved.", "geneva": "Doeth not the poore chuse out a tree that will not rot, for an oblation? he seeketh also vnto him a cunning workeman, to prepare an image, that shall not be moued.", "wycliffe": "A wijs crafti man chees a strong tre, and vnable to be rotun; he sekith how he schal ordeyne a symylacre, that schal not be mouyd.", "rotherham": "The needy offerer, of a tree that will not rot, maketh choice,—A skilled artificer, seeketh he out for himself to construct an image that shall not totter,", "darby": "He that is impoverished, so that he hath no offering, chooseth a tree that doth not rot; he seeketh unto him a skilled workman to prepare a graven image that shall not be moved.", "twenty": "", "jps": "A holm-oak is set apart, he chooseth a tree that will not rot; he seeketh unto him a cunning craftsman to set up an image, that shall not be moved.", "acv": "He who is too impoverished for such an oblation chooses a tree that will not rot. He seeks for him a skilful workman to set up a graven image that shall not be moved.", "anderson": "", "haweis": "", "noyes": "He that is too poor to make an oblation Chooseth a piece of wood that will not rot; He seeketh for himself a skilful artificer, To prepare an image that shall not be moved.", "webster": "He that [is] so impoverished that he hath no oblation chooseth a tree [that] will not rot; he seeketh for himself a skillful workman to prepare a graven image [that] shall not be moved.", "vulgate": "forte lignum et inputribile elegit artifex sapiens quaerit quomodo statuat simulacrum quod non moveatur;", "brenton": "For the artificer chooses out a wood that will not rot, and will wisely enquire how he shall set up his image, and that so that it should not be moved."}}, {"v": 21, "ref": "40:21", "o": "הֲ/ל֤וֹא תֵֽדְעוּ֙ הֲ/ל֣וֹא תִשְׁמָ֔עוּ הֲ/ל֛וֹא הֻגַּ֥ד מֵ/רֹ֖אשׁ לָ/כֶ֑ם הֲ/לוֹא֙ הֲבִ֣ינֹתֶ֔ם מוֹסְד֖וֹת הָ/אָֽרֶץ", "en": {"kjv": "Have ye not known? have ye not heard? hath it not been told you from the beginning? have ye not understood from the foundations of the earth?", "web": "Haven’t you known? Haven’t you heard, yet? Haven’t you been told from the beginning? Haven’t you understood from the foundations of the earth?", "bsb": "Do you not know? Have you not heard? Has it not been declared to you from the beginning? Have you not understood since the foundation of the earth?", "asv": "Have ye not known? have ye not heard? hath it not been told you from the beginning? have ye not understood from the foundations of the earth?", "ylt": "Do ye not know--do ye not hear? Hath it not been declared from the first to you? Have ye not understood From the foundations of the earth?", "dra": "Do you not know? hath it not been heard? hath it not been told you from the beginning? have you not understood the foundations of the earth?", "bbe": "Have you no knowledge of it? has it not come to your ears? has not news of it been given to you from the first? has it not been clear to you from the time when the earth was placed on its base?", "geneva": "Know ye nothing? haue ye not heard it? hath it not bene tolde you from the beginning? haue ye not vnderstand it by the foundation of the earth?", "wycliffe": "Whether ye witen not? whether ye herden not? whether it was not teld to you fro the begynnynge? whether ye vndurstoden not the foundementis of erthe?", "rotherham": "Have ye never taken note? Have ye never heard? Hath it not from the beginning, been told you? Have ye not been led to discern, from the foundations of the earth?", "darby": "— Do ye not know? Have ye not heard? Hath it not been told you from the beginning? Have ye not understood the foundation of the earth?", "twenty": "", "jps": "Know ye not? hear ye not? Hath it not been told you from the beginning? Have ye not understood the foundations of the earth?", "acv": "Have ye not known? Have yet not heard? Has it not been told you from the beginning? Have ye not understood from the foundations of the earth?", "anderson": "", "haweis": "", "noyes": "Do ye not know? Have ye not heard? Hath it not been declared to you from the beginning? Have ye not considered the foundations of the earth?", "webster": "Have ye not known? have ye not heard? hath it not been told you from the beginning? have ye not understood from the foundations of the earth?", "vulgate": "numquid non scietis numquid non audietis numquid non adnuntiatum est ab initio vobis numquid non intellexistis fundamenta terrae;", "brenton": "Will ye not know? will ye not hear? has it not been told you of old? Have ye not known the foundations of the earth?"}}, {"v": 22, "ref": "40:22", "o": "הַ/יֹּשֵׁב֙ עַל ח֣וּג הָ/אָ֔רֶץ וְ/יֹשְׁבֶ֖י/הָ כַּ/חֲגָבִ֑ים הַ/נּוֹטֶ֤ה כַ/דֹּק֙ שָׁמַ֔יִם וַ/יִּמְתָּחֵ֥/ם כָּ/אֹ֖הֶל לָ/שָֽׁבֶת", "en": {"kjv": "It is he that sitteth upon the circle of the earth, and the inhabitants thereof are as grasshoppers; that stretcheth out the heavens as a curtain, and spreadeth them out as a tent to dwell in:", "web": "It is he who sits above the circle of the earth, and its inhabitants are like grasshoppers; who stretches out the heavens like a curtain, and spreads them out like a tent to dwell in;", "bsb": "He sits enthroned above the circle of the earth; its dwellers are like grasshoppers. He stretches out the heavens like a curtain, and spreads them out like a tent to dwell in.", "asv": "It is he that sitteth above the circle of the earth, and the inhabitants thereof are as grasshoppers; that stretcheth out the heavens as a curtain, and spreadeth them out as a tent to dwell in;", "ylt": "He who is sitting on the circle of the earth, And its inhabitants are as grasshoppers, He who is stretching out as a thin thing the heavens, And spreadeth them as a tent to dwell in.", "dra": "It is he that sitteth upon the globe of the earth, and the inhabitants thereof are as locusts: he that stretcheth out the heavens as nothing, and spreadeth them out as a tent to dwell in.", "bbe": "It is he who is seated over the arch of the earth, and the people in it are as small as locusts; by him the heavens are stretched out like an arch, and made ready like a tent for a living-place.", "geneva": "He sitteth vpon the circle of the earth, and the inhabitants thereof are as grashoppers, hee stretcheth out ye heauens, as a curtaine, and spreadeth them out, as a tent to dwell in.", "wycliffe": "Which sittith on the cumpas of erthe, and the dwelleris therof ben as locustis; which stretchith forth heuenes as nouyt, and spredith abrood tho as a tabernacle to dwelle.", "rotherham": "It is he who sitteth upon the circle of the earth, While the inhabitants thereof are, as grass-hoppers,—Who stretcheth forth, as a curtain, the heavens, And spreadeth them out as a tent to dwell in;", "darby": "[It is] he that sitteth upon the circle of the earth, and the inhabitants thereof are as grasshoppers; that stretcheth out the heavens as a gauze curtain, and spreadeth them out as a tent to dwell in;", "twenty": "", "jps": "It is He that sitteth above the circle of the earth, and the inhabitants thereof are as grasshoppers; that stretcheth out the heavens as a curtain, and spreadeth them out as a tent to dwell in;", "acv": "It is he who sits above the circle of the earth, and the inhabitants thereof are as grasshoppers, who stretches out the heavens as a curtain, and spreads them out as a tent to dwell in,", "anderson": "", "haweis": "", "noyes": "It is He that sitteth above the circle of the earth, And the inhabitants are to him as grasshoppers; That stretcheth out the heavens as a canopy, And spreadeth them out as a tent to dwell in;", "webster": "[It is] he that sitteth upon the circle of the earth, and its inhabitants [are] as grasshoppers; that stretcheth out the heavens as a curtain, and spreadeth them out as a tent to dwell in:", "vulgate": "qui sedet super gyrum terrae et habitatores eius sunt quasi lucustae qui extendit velut nihilum caelos et expandit eos sicut tabernaculum ad inhabitandum;", "brenton": "It is he that comprehends the circle of the earth, and the inhabitants in it are as grasshoppers; he that set up the heaven as a chamber, and stretched it out as a tent to dwell in:"}}, {"v": 23, "ref": "40:23", "o": "הַ/נּוֹתֵ֥ן רוֹזְנִ֖ים לְ/אָ֑יִן שֹׁ֥פְטֵי אֶ֖רֶץ כַּ/תֹּ֥הוּ עָשָֽׂה", "en": {"kjv": "That bringeth the princes to nothing; he maketh the judges of the earth as vanity.", "web": "who brings princes to nothing; who makes the judges of the earth like meaningless.", "bsb": "He brings the princes to nothing and makes the rulers of the earth meaningless.", "asv": "that bringeth princes to nothing; that maketh the judges of the earth as vanity.", "ylt": "He who is making princes become nothing, Judges of earth as emptiness hath made;", "dra": "He that bringeth the searchers of secrets to nothing, that hath made the judges of the earth as vanity.", "bbe": "He makes rulers come to nothing; the judges of the earth are of no value.", "geneva": "He bringeth the princes to nothing, and maketh the iudges of the earth, as vanitie,", "wycliffe": "Which yyueth the sercheris of priuytees, as if thei be not, and made the iugis of erthe as a veyn thing.", "rotherham": "Who delivereth dignitaries to nothingness,—Judges of earth, like a desolation, hath he made:", "darby": "that bringeth the princes to nothing, that maketh the judges of the earth as vanity.", "twenty": "", "jps": "That bringeth princes to nothing; He maketh the judges of the earth as a thing of nought.", "acv": "who brings rulers to nothing, who makes the judges of the earth as vanity.", "anderson": "", "haweis": "", "noyes": "That bringeth princes to nothing, And reduceth the rulers of the earth to vanity.", "webster": "That bringeth the princes to nothing; he maketh the judges of the earth as vanity.", "vulgate": "qui dat secretorum scrutatores quasi non sint iudices terrae velut inane fecit;", "brenton": "he that appoints princes to rule as nothing, and has made the earth as nothing."}}, {"v": 24, "ref": "40:24", "o": "אַ֣ף בַּל נִטָּ֗עוּ אַ֚ף בַּל זֹרָ֔עוּ אַ֛ף בַּל שֹׁרֵ֥שׁ בָּ/אָ֖רֶץ גִּזְעָ֑/ם וְ/גַם נָשַׁ֤ף בָּ/הֶם֙ וַ/יִּבָ֔שׁוּ וּ/סְעָרָ֖ה כַּ/קַּ֥שׁ תִּשָּׂאֵֽ/ם", "en": {"kjv": "Yea, they shall not be planted; yea, they shall not be sown: yea, their stock shall not take root in the earth: and he shall also blow upon them, and they shall wither, and the whirlwind shall take them away as stubble.", "web": "They are planted scarcely. They are sown scarcely. Their stock has scarcely taken root in the ground. He merely blows on them, and they wither, and the whirlwind takes them away as stubble.", "bsb": "No sooner are they planted, no sooner are they sown, no sooner have their stems taken root in the ground, than He blows on them and they wither, and a whirlwind sweeps them away like stubble.", "asv": "Yea, they have not been planted; yea, they have not been sown; yea, their stock hath not taken root in the earth: moreover he bloweth upon them, and they wither, and the whirlwind taketh them away as stubble.", "ylt": "Yea, they have not been planted, Yea, they have not been sown, Yea, not taking root in the earth is their stock, And also He hath blown upon them, and they wither, And a whirlwind as stubble taketh them away.", "dra": "And surely their stock was neither planted, nor sown, nor rooted in the earth: suddenly he hath blown upon them, and they are withered, and a whirlwind shall take them away as stubble.", "bbe": "They have only now been planted, and their seed put into the earth, and they have only now taken root, when he sends out his breath over them and they become dry, and the storm-wind takes them away like dry grass.", "geneva": "As though they were not plated, as though they were not sowen, as though their stocke tooke no roote in the earth: for he did euen blow vpon them, and they withered, and the whirlewinde will take them away as stubble.", "wycliffe": "And sotheli whanne the stok of hem is nether plauntid, nether is sowun, nether is rootid in erthe, he bleew sudenli on hem, and thei drieden vp, and a whirle wynd schal take hem awei as stobil.", "rotherham": "Scarcely have they been planted, Scarcely have they been sown, Scarcely hath their stock, begun to take root in the earth, When he hath just blown upon them and they have withered, And, a whirlwind, as though they had been chaff, carrieth them away.", "darby": "Scarcely are they planted, scarcely are they sown, scarcely hath their stock taken root in the earth, but he also bloweth upon them and they wither, and the whirlwind taketh them away as stubble.", "twenty": "", "jps": "Scarce are they planted, scarce are they sown, scarce hath their stock taken root in the earth; when He bloweth upon them, they wither, and the whirlwind taketh them away as stubble.", "acv": "Yea, they have not been planted. Yea, they have not been sown. Yea, their stock has not taken root in the earth. Moreover he blows upon them, and they wither, and the whirlwind takes them away as stubble.", "anderson": "", "haweis": "", "noyes": "Yea, scarcely are they planted, scarcely are they sown, Scarcely hath their stem taken root in the ground, When He bloweth upon them and they wither, And the whirlwind beareth them away like stubble.", "webster": "Yes, they shall not be planted; yes, they shall not be sown: yes, their stock shall not take root in the earth: and he shall also blow upon them, and they shall wither, and the whirlwind shall take them away as stubble.", "vulgate": "et quidem neque plantatos neque satos neque radicato in terra trunco eorum repente flavit in eos et aruerunt et turbo quasi stipulam auferet eos;", "brenton": "For they shall not plant, neither shall they sow, neither shall their root be fixed in the ground: he has blown upon them, and they are withered, and a storm shall carry them away like sticks."}}, {"v": 25, "ref": "40:25", "o": "וְ/אֶל מִ֥י תְדַמְּי֖וּ/נִי וְ/אֶשְׁוֶ֑ה יֹאמַ֖ר קָדֽוֹשׁ", "en": {"kjv": "To whom then will ye liken me, or shall I be equal? saith the Holy One.", "web": "“To whom then will you liken me? Who is my equal?” says the Holy One.", "bsb": "“To whom will you liken Me, or who is My equal?” asks the Holy One.", "asv": "To whom then will ye liken me, that I should be equal to him? saith the Holy One.", "ylt": "And unto whom do ye liken Me, And am I equal? saith the Holy One.", "dra": "And to whom have ye likened me, or made me equal, saith the Holy One?", "bbe": "Who then seems to you to be my equal? says the Holy One.", "geneva": "To whom nowe will ye liken me, that I should be like him, saith the Holy one?", "wycliffe": "And to what thing `ye han licned me, and han maad euene? seith the hooli.", "rotherham": "Unto whom then, can ye liken me, or can I be equal? Saith the Holy One.", "darby": "To whom then will ye liken me, or shall I be equal? saith the Holy One.", "twenty": "", "jps": "To whom then will ye liken Me, that I should be equal? saith the Holy One.", "acv": "To whom then will ye liken me, that I should be equal to him? says the Holy One.", "anderson": "", "haweis": "", "noyes": "To whom then will ye liken me, And to whom shall I be compared? Saith the Holy One.", "webster": "To whom then will ye liken me, or shall I be equaled? saith the Holy One.", "vulgate": "et cui adsimilastis me et adaequastis dicit Sanctus;", "brenton": "Now then to whom have ye compared me, that I may be exalted? saith the Holy One."}}, {"v": 26, "ref": "40:26", "o": "שְׂאוּ מָר֨וֹם עֵינֵי/כֶ֤ם וּ/רְאוּ֙ מִי בָרָ֣א אֵ֔לֶּה הַ/מּוֹצִ֥יא בְ/מִסְפָּ֖ר צְבָאָ֑/ם לְ/כֻלָּ/ם֙ בְּ/שֵׁ֣ם יִקְרָ֔א מֵ/רֹ֤ב אוֹנִים֙ וְ/אַמִּ֣יץ כֹּ֔חַ אִ֖ישׁ לֹ֥א נֶעְדָּֽר", "en": {"kjv": "Lift up your eyes on high, and behold who hath created these things, that bringeth out their host by number: he calleth them all by names by the greatness of his might, for that he is strong in power; not one faileth.", "web": "Lift up your eyes on high, and see who has created these, who brings out their army by number. He calls them all by name. by the greatness of his might, and because he is strong in power, Not one is lacking.", "bsb": "Lift up your eyes on high: Who created all these? He leads forth the starry host by number; He calls each one by name. Because of His great power and mighty strength, not one of them is missing.", "asv": "Lift up your eyes on high, and see who hath created these, that bringeth out their host by number; he calleth them all by name; by the greatness of his might, and for that he is strong in power, not one is lacking.", "ylt": "Lift up on high your eyes, And see--who hath prepared these? He who is bringing out by number their host, To all of them by name He calleth, By abundance of strength (And he is strong in power) not one is lacking.", "dra": "Lift up your eyes on high, and see who hath created these things: who bringeth out their host by number, and calleth them all by their names: by the greatness of his might, and strength, and power, not one of them was missing.", "bbe": "Let your eyes be lifted up on high, and see: who has made these? He who sends out their numbered army: who has knowledge of all their names: by whose great strength, because he is strong in power, all of them are in their places.", "geneva": "Lift vp your eyes on hie, and beholde who hath created these things, and bringeth out their armies by nomber, and calleth them all by names? by the greatnesse of his power and mightie strength nothing faileth.", "wycliffe": "Reise youre iyen an hiy, and se ye, who made these thingis of nouyt; which ledith out in noumbre the kniythod of tho, and clepith alle bi name, for the multitude of his strengthe, and stalworthnesse, and vertu; nether o residue thing was.", "rotherham": "Lift on high your eyes—and see who hath created these, That bringeth forth, by number, their host,—To all of them by name, doth call, Because of the abundance of vigour and alertness of strength, not one, is missing!", "darby": "Lift up your eyes on high, and see! Who hath created these things, bringing out their host by number? He calleth them all by name; through the greatness of his might and strength of power, not one faileth.", "twenty": "", "jps": "Lift up your eyes on high, and see: who hath created these? He that bringeth out their host by number, He calleth them all by name; by the greatness of His might, and for that He is strong in power, not one faileth.", "acv": "Lift up your eyes on high, and see who has created these, who brings out their host by number. He calls them all by name, by the greatness of his might. And because he is strong in power, not one is lacking.", "anderson": "", "haweis": "", "noyes": "Lift up your eyes to the heavens, and behold! Who hath created these? He draweth forth their host by number, He calleth them all by name; Through the greatness of his strength and the mightiness of his power, Not one of them faileth to appear.", "webster": "Lift up your eyes on high, and behold who hath created these [things], that bringeth out their host by number: he calleth them all by names, by the greatness of his might, for that [he] is strong in power; not one faileth.", "vulgate": "levate in excelsum oculos vestros et videte quis creavit haec qui educit in numero militiam eorum et omnes ex nomine vocat prae multitudine fortitudinis et roboris virtutisque eius neque unum reliquum fuit;", "brenton": "Lift up your eyes on high, and see, who has displayed all these things? even he that brings forth his host by number: he shall call them all by name by means of his great glory, and by the power of his might: nothing has escaped thee."}}, {"v": 27, "ref": "40:27", "o": "לָ֤/מָּה תֹאמַר֙ יַֽעֲקֹ֔ב וּ/תְדַבֵּ֖ר יִשְׂרָאֵ֑ל נִסְתְּרָ֤ה דַרְכִּ/י֙ מֵֽ/יְהוָ֔ה וּ/מֵ/אֱלֹהַ֖/י מִשְׁפָּטִ֥/י יַעֲבֽוֹר", "en": {"kjv": "Why sayest thou, O Jacob, and speakest, O Israel, My way is hid from the Lord, and my judgment is passed over from my God?", "web": "Why do you say, Jacob, and speak, Israel, “My way is hidden from Yahweh, and the justice due me is disregarded by my God?”", "bsb": "Why do you say, O Jacob, and why do you assert, O Israel, “My way is hidden from the LORD, and my claim is ignored by my God”?", "asv": "Why sayest thou, O Jacob, and speakest, O Israel, My way is hid from Jehovah, and the justice due to me is passed away from my God?", "ylt": "Why sayest thou, O Jacob? and speakest thou, O Israel? `My way hath been hid from Jehovah, And from my God my judgment passeth over.'", "dra": "Why sayest thou, O Jacob, and speakest, O Israel: My way is hid from the Lord, and my judgment is passed over from my God?", "bbe": "Why do you say, O Jacob, such words as these, O Israel, The Lord's eyes are not on my way, and my God gives no attention to my cause?", "geneva": "Why sayest thou, O Iaakob, and speakest O Israel, My way is hid from the Lord, and my iudgement is passed ouer of my God?", "wycliffe": "Whi seist thou, Jacob, and spekist thou, Israel, My weie is hid fro the Lord, and my doom passide fro my God?", "rotherham": "Wherefore, shouldest thou say, O Jacob, or speak, O Israel,—Hidden is my path from Yahweh, And from my God, my vindication, will pass?", "darby": "Why sayest thou, Jacob, and speakest, O Israel, My way is hid from Jehovah, and my right is passed away from myGod?", "twenty": "", "jps": "Why sayest thou, O Jacob, and speakest, O Israel: 'My way is hid from HaShem, and my right is passed over from my G-d'?", "acv": "Why do thou say, O Jacob, and speak, O Israel, My way is hid from Jehovah. And the justice due to me is passed away from my God?", "anderson": "", "haweis": "", "noyes": "Why sayest thou, O Jacob, and speakest, O Israel, \"My way is hidden from Jehovah, My cause passeth by before my God\"?", "webster": "Why sayest thou, O Jacob, and speakest, O Israel, My way is hid from the LORD, and my judgment is passed over by my God?", "vulgate": "quare dicis Iacob et loqueris Israhel abscondita est via mea a Domino et a Deo meo iudicium meum transibit;", "brenton": "For say not thou, O Jacob, and why hast thou spoken, Israel, saying, My way is hid from God, and my God has taken away my judgement, and has departed?"}}, {"v": 28, "ref": "40:28", "o": "הֲ/ל֨וֹא יָדַ֜עְתָּ אִם לֹ֣א שָׁמַ֗עְתָּ אֱלֹהֵ֨י עוֹלָ֤ם יְהוָה֙ בּוֹרֵא֙ קְצ֣וֹת הָ/אָ֔רֶץ לֹ֥א יִיעַ֖ף וְ/לֹ֣א יִיגָ֑ע אֵ֥ין חֵ֖קֶר לִ/תְבוּנָתֽ/וֹ", "en": {"kjv": "Hast thou not known? hast thou not heard, that the everlasting God, the Lord, the Creator of the ends of the earth, fainteth not, neither is weary? there is no searching of his understanding.", "web": "Haven’t you known? Haven’t you heard? The everlasting God, Yahweh, The Creator of the ends of the earth, doesn’t faint. He isn’t weary. His understanding is unsearchable.", "bsb": "Do you not know? Have you not heard? The LORD is the everlasting God, the Creator of the ends of the earth. He will not grow tired or weary; His understanding is beyond searching out.", "asv": "Hast thou not known? hast thou not heard? The everlasting God, Jehovah, the Creator of the ends of the earth, fainteth not, neither is weary; there is no searching of his understanding.", "ylt": "Hast thou not known? hast thou not heard? The God of the age--Jehovah, Preparer of the ends of the earth, Is not wearied nor fatigued, There is no searching of His understanding.", "dra": "Knowest thou not, or hast thou not heard? the Lord is the everlasting God, who hath created the ends of the earth: he shall not faint, nor labour, neither is there any searching out of his wisdom.", "bbe": "Have you no knowledge of it? has it not come to your ears? The eternal God, the Lord, the Maker of the ends of the earth, is never feeble or tired; there is no searching out of his wisdom.", "geneva": "Knowest thou not? or hast thou not heard, that the euerlasting God, the Lord hath created the endes of the earth? he neither fainteth, nor is wearie: there is no searching of his vnderstanding.", "wycliffe": "Whether thou knowist not, ether herdist thou not? God, euerlastynge Lord, that made of nouyt the endis of erthe, schal not faile, nether schal trauele, nether enserchyng of his wisdom is.", "rotherham": "Hast thou not known, Hast thou not heard, That The God of age-past time—Yahweh The Creator of the ends of the earth Fainteth not neither groweth weary—There is no searching of his understanding:", "darby": "Dost thou not know, hast thou not heard, that the everlastingGod, Jehovah, the Creator of the ends of the earth, fainteth not nor tireth? There is no searching of his understanding.", "twenty": "", "jps": "Hast thou not known? hast thou not heard that the everlasting G-d, HaShem, the Creator of the ends of the earth, fainteth not, neither is weary? His discernment is past searching out.", "acv": "Have thou not known? Have thou not heard? The everlasting God, Jehovah, the Creator of the ends of the earth, faints not, nor is weary. There is no searching of his understanding.", "anderson": "", "haweis": "", "noyes": "Do ye not know? Have ye not heard? Jehovah is an everlasting God, The creator of the ends of the earth; He fainteth not, nor is he weary; His understanding is unsearchable.", "webster": "Hast thou not known? hast thou not heard, [that] the everlasting God, the LORD, the Creator of the ends of the earth, fainteth not, neither is weary? [there is] no searching of his understanding.", "vulgate": "numquid nescis aut non audisti Deus sempiternus Dominus qui creavit terminos terrae non deficiet neque laborabit nec est investigatio sapientiae eius;", "brenton": "And now, hast thou not known? hast thou not heard? the eternal God, the God that formed the ends of the earth, shall not hunger, nor be weary, and there is no searching of his understanding."}}, {"v": 29, "ref": "40:29", "o": "נֹתֵ֥ן לַ/יָּעֵ֖ף כֹּ֑חַ וּ/לְ/אֵ֥ין אוֹנִ֖ים עָצְמָ֥ה יַרְבֶּֽה", "en": {"kjv": "He giveth power to the faint; and to them that have no might he increaseth strength.", "web": "He gives power to the weak. He increases the strength of him who has no might.", "bsb": "He gives power to the faint and increases the strength of the weak.", "asv": "He giveth power to the faint; and to him that hath no might he increaseth strength.", "ylt": "He is giving power to the weary, And to those not strong He increaseth might.", "dra": "It is he that giveth strength to the weary, and increaseth force and might to them that are not.", "bbe": "He gives power to the feeble, increasing the strength of him who has no force.", "geneva": "But he giueth strength vnto him that fainteth, and vnto him that hath no strength, he encreaseth power.", "wycliffe": "That yyueth vertu to the weeri, and strengthe to hem that ben not, and multiplieth stalworthnesse.", "rotherham": "Giving to him that fainteth, strength, And to him that hath no vigour, he causeth, power to abound?", "darby": "He giveth power to the faint; and to him that hath no might he increaseth strength.", "twenty": "", "jps": "He giveth power to the faint; and to him that hath no might He increaseth strength.", "acv": "He gives power to the faint. And to him who has no might he increases strength.", "anderson": "", "haweis": "", "noyes": "He giveth power to the faint; To the feeble abundant strength.", "webster": "He giveth power to the faint; and to [them that have] no might he increaseth strength.", "vulgate": "qui dat lasso virtutem et his qui non sunt fortitudinem et robur multiplicat;", "brenton": "He gives strength to the hungry, and sorrow to them that are not suffering."}}, {"v": 30, "ref": "40:30", "o": "וְ/יִֽעֲפ֥וּ נְעָרִ֖ים וְ/יִגָ֑עוּ וּ/בַחוּרִ֖ים כָּשׁ֥וֹל יִכָּשֵֽׁלוּ", "en": {"kjv": "Even the youths shall faint and be weary, and the young men shall utterly fall:", "web": "Even the youths faint and get weary, and the young men utterly fall;", "bsb": "Even youths grow tired and weary, and young men stumble and fall.", "asv": "Even the youths shall faint and be weary, and the young men shall utterly fall:", "ylt": "Even youths are wearied and fatigued, And young men utterly stumble,", "dra": "You shall faint, and labour, and young men shall fall by infirmity.", "bbe": "Even the young men will become feeble and tired, and the best of them will come to the end of his strength;", "geneva": "Euen the yong men shall faint, and be wearie, and the yong men shall stumble and fall.", "wycliffe": "Children schulen faile, and schulen trauele, and yonge men schulen falle doun in her sikenesse.", "rotherham": "Youths both faint and grow weary, And, young warriors—they fall, they fall;", "darby": "Even the youths shall faint and shall tire, and the young men shall stumble and fall;", "twenty": "", "jps": "Even the youths shall faint and be weary, and the young men shall utterly fall;", "acv": "Even the youths shall faint and be weary, and the young men shall utterly fall.", "anderson": "", "haweis": "", "noyes": "The youths shall faint and be weary, And the young warriors shall utterly fall.", "webster": "Even the youths shall faint and be weary, and the young men shall utterly fall:", "vulgate": "deficient pueri et laborabunt et iuvenes in infirmitate cadent;", "brenton": "For the young men shall hunger, and the youths shall be weary, and the choice men shall be powerless:"}}, {"v": 31, "ref": "40:31", "o": "וְ/קוֹיֵ֤ יְהוָה֙ יַחֲלִ֣יפוּ כֹ֔חַ יַעֲל֥וּ אֵ֖בֶר כַּ/נְּשָׁרִ֑ים יָר֨וּצוּ֙ וְ/לֹ֣א יִיגָ֔עוּ יֵלְכ֖וּ וְ/לֹ֥א יִיעָֽפוּ", "en": {"kjv": "But they that wait upon the Lord shall renew their strength; they shall mount up with wings as eagles; they shall run, and not be weary; and they shall walk, and not faint.", "web": "But those who wait for Yahweh will renew their strength. They will mount up with wings like eagles. They will run, and not be weary. They will walk, and not faint.", "bsb": "But those who wait upon the LORD will renew their strength; they will mount up with wings like eagles; they will run and not grow weary, they will walk and not faint.", "asv": "but they that wait for Jehovah shall renew their strength; they shall mount up with wings as eagles; they shall run, and not be weary; they shall walk, and not faint.", "ylt": "But those expecting Jehovah pass to power, They raise up the pinion as eagles, They run and are not fatigued, They go on and do not faint!", "dra": "But they that hope in the Lord shall renew their strength, they shall take wings as eagles, they shall run and not be weary, they shall walk and not faint.", "bbe": "But those who are waiting for the Lord will have new strength; they will get wings like eagles: running, they will not be tired, and walking, they will have no weariness.", "geneva": "But they that waite vpon the Lord, shall renue their strength: they shall lift vp the wings as the eagles: they shall runne, and not be wearie, and they shall walke and not faint.", "wycliffe": "But thei that hopen in the Lord, schulen chaunge strengthe, thei schulen take fetheris as eglis; thei schulen renne, and schulen not trauele; thei schulen go, and schulen not faile.", "rotherham": "But, they who wait for Yahweh, shall renew their strength, They shall mount on strong pinion like eagles,—They shall run and not grow weary, They shall walk and not faint.", "darby": "but they that wait upon Jehovah shall renew [their] strength: they shall mount up with wings as eagles; they shall run, and not tire; they shall walk, and not faint.", "twenty": "", "jps": "But they that wait for HaShem shall renew their strength; they shall mount up with wings as eagles; they shall run, and not be weary; they shall walk, and not faint.", "acv": "But those who wait for Jehovah shall renew their strength. They shall mount up with wings as eagles. They shall run, and not be weary. They shall walk, and not faint.", "anderson": "", "haweis": "", "noyes": "But they that trust in Jehovah shall renew their strength; They shall mount up with wings like eagles; They shall run and not be weary; They shall walk and not faint.", "webster": "But they that wait upon the LORD shall renew [their] strength; they shall mount up with wings as eagles; they shall run, and not be weary; they shall walk, and not faint.", "vulgate": "qui autem sperant in Domino mutabunt fortitudinem adsument pinnas sicut aquilae current et non laborabunt ambulabunt et non deficient;", "brenton": "but they that wait on God shall renew their strength; they shall put forth new feathers like eagles; they shall run, and not be weary; they shall walk, and not hunger."}}]}, {"c": 41, "verses": [{"v": 1, "ref": "41:1", "o": "הַחֲרִ֤ישׁוּ אֵלַ/י֙ אִיִּ֔ים וּ/לְאֻמִּ֖ים יַחֲלִ֣יפוּ כֹ֑חַ יִגְּשׁוּ֙ אָ֣ז יְדַבֵּ֔רוּ יַחְדָּ֖ו לַ/מִּשְׁפָּ֥ט נִקְרָֽבָה", "en": {"kjv": "Keep silence before me, O islands; and let the people renew their strength: let them come near; then let them speak: let us come near together to judgment.", "web": "“Keep silent before me, islands, and let the peoples renew their strength. Let them come near, then let them speak. Let’s meet together for judgment.", "bsb": "“Be silent before Me, O islands, and let the peoples renew their strength. Let them come forward and testify; let us together draw near for judgment.", "asv": "Keep silence before me, O islands; and let the peoples renew their strength: let them come near; then let them speak; let us come near together to judgment.", "ylt": "Keep silent towards Me, O isles, And the peoples pass on to power, They come nigh, then they speak, `Together--to judgment we draw near.'", "dra": "Let the islands keep silence before me, and the nations take new strength: let them come near, and then speak, let us come near to judgment together.", "bbe": "Come quietly before me, O sea-lands, and let the peoples get together their strength: let them come near; then let them say what they have to say: let us put forward our cause against one another.", "geneva": "Keep silence before mee, O ylands, and let the people renue their strength: let the come neere, and let them speake: let vs come together into iudgement.", "wycliffe": "Iles, be stille to me, and folkis chaunge strengthe; neiye thei, and thanne speke thei; neiye we togidere to doom.", "rotherham": "Be silent [and hearken] unto me, O ye Coastlands, And let the Races of Men renew their strength,—Let them approach, then, let them speak, Together, for controversy, let us draw near:—", "darby": "Keep silence before me, islands; and let the peoples renew [their] strength: let them come near; then let them speak: let us draw near together to judgment.", "twenty": "", "jps": "Keep silence before Me, O islands, and let the peoples renew their strength; let them draw near, then let them speak; let us come near together to judgment.", "acv": "Keep silence before me, O islands, and let the peoples renew their strength. Let them come near, then let them speak. Let us come near together to judgment.", "anderson": "", "haweis": "", "noyes": "Keep silence, and hear me, ye distant lands. Ye nations, gather your strength! Let them come near; then let them speak; Let us go together into judgment.", "webster": "Keep silence before me, O isles; and let the people renew [their] strength: let them come near; then let them speak: let us come near together to judgment.", "vulgate": "taceant ad me insulae et gentes mutent fortitudinem accedant et tunc loquantur simul ad iudicium propinquemus;", "brenton": "Hold a feast to me, ye islands: for the princes shall renew their strength: let them draw nigh and speak together: then let them declare judgment."}}, {"v": 2, "ref": "41:2", "o": "מִ֤י הֵעִיר֙ מִ/מִּזְרָ֔ח צֶ֖דֶק יִקְרָאֵ֣/הוּ לְ/רַגְל֑/וֹ יִתֵּ֨ן לְ/פָנָ֤י/ו גּוֹיִם֙ וּ/מְלָכִ֣ים יַ֔רְדְּ יִתֵּ֤ן כֶּֽ/עָפָר֙ חַרְבּ֔/וֹ כְּ/קַ֥שׁ נִדָּ֖ף קַשְׁתּֽ/וֹ", "en": {"kjv": "Who raised up the righteous man from the east, called him to his foot, gave the nations before him, and made him rule over kings? he gave them as the dust to his sword, and as driven stubble to his bow.", "web": "Who has raised up one from the east? Who called him to his foot in righteousness? He hands over nations to him, and makes him rule over kings. He gives them like the dust to his sword, like the driven stubble to his bow.", "bsb": "Who has aroused one from the east and called him to his feet in righteousness? He hands nations over to him and subdues kings before him. He turns them to dust with his sword, to windblown chaff with his bow.", "asv": "Who hath raised up one from the east, whom he calleth in righteousness to his foot? he giveth nations before him, and maketh him rule over kings; he giveth them as the dust to his sword, as the driven stubble to his bow.", "ylt": "Who stirred up from the east a righteous one? He calleth him to His foot, He giveth before him nations, And kings He causeth him to rule, He giveth them as dust to his sword, As driven stubble to his bow.", "dra": "Who hath raised up the just one from the east, hath called him to follow him? he shall give the nations in his sight, and he shall rule over kings: he shall give them as the dust to his sword, as stubble driven by the wind, to his bow.", "bbe": "Who sent out from the east one who is right wherever he goes? he gives the nations into his hands, and makes him ruler over kings; he gives them as the dust to his sword, as dry stems before the wind to his bow.", "geneva": "Who raised vp iustice from the East, and called him to his foote? and gaue the nations before him, and subdued the Kings? he gaue them as dust to his sword, and as scattered stubble vnto his bowe.", "wycliffe": "Who reiside the iust man fro the eest, and clepide hym to sue hym silf? He schal yyue folkis in his siyt, and he schal welde kyngis; he schal yyue as dust to his swerd, and as stobil `that is rauyschid of the wynd, to his bowe.", "rotherham": "Who roused up one from the East, In righteousness, called him to his feet,—Set before him nations And over kings, caused him to rule, His sword, made [them] like dust, His bow like driven chaff:", "darby": "Who raised up from the east him whom righteousness calleth to its foot? He gave the nations before him, and caused him to have dominion over kings; he gave them as dust to his sword, as driven stubble to his bow.", "twenty": "", "jps": "Who hath raised up one from the east, at whose steps victory attendeth? He giveth nations before him, and maketh him rule over kings; his sword maketh them as the dust, his bow as the driven stubble.", "acv": "Who raised up the righteous man from the east, calls him to his foot, gives nations before him, and makes him rule over kings? He gives them as the dust to his sword, as the driven stubble to his bow.", "anderson": "", "haweis": "", "noyes": "Who hath raised up from the region of the East Him whom victory meeteth in his march? Who hath subdued nations before him, And given him dominion over kings? Who made their swords like dust, And their bows like driven stubble?", "webster": "Who raised up the righteous [man] from the east, called him to his foot, gave the nations before him, and made [him] rule over kings? he gave [them] as the dust to his sword, [and] as driven stubble to his bow.", "vulgate": "quis suscitavit ab oriente iustum vocavit eum ut sequeretur se dabit in conspectu eius gentes et reges obtinebit dabit quasi pulverem gladio eius sicut stipulam vento raptam arcui eius;", "brenton": "Who raised up righteousness from the east, and called it to his feet, so that it should go? shall appoint it an adversary of Gentiles, and shall dismay kings, and bury their swords in the earth, and cast forth their bows and arrows as sticks?"}}, {"v": 3, "ref": "41:3", "o": "יִרְדְּפֵ֖/ם יַעֲב֣וֹר שָׁל֑וֹם אֹ֥רַח בְּ/רַגְלָ֖י/ו לֹ֥א יָבֽוֹא", "en": {"kjv": "He pursued them, and passed safely; even by the way that he had not gone with his feet.", "web": "He pursues them, and passes by safely, Even by a way that he had not gone with his feet.", "bsb": "He pursues them, going on safely, hardly touching the path with his feet.", "asv": "He pursueth them, and passeth on safely, even by a way that he had not gone with his feet.", "ylt": "He pursueth them, he passeth over in safety A path with his feet he entereth not.", "dra": "He shall pursue them, he shall pass in peace, no path shall appear after his feet.", "bbe": "He goes after them safely, not touching the road with his feet.", "geneva": "He pursued them, and passed safely by the way that he had not gone with his feete.", "wycliffe": "He schal pursue hem, he schal go in pees; a path schal not appere in hise feet.", "rotherham": "He pursued them passed along safely,—Upon the path of his own feet, entered he not?", "darby": "He pursued them, he passed on in safety, by a way he had never come with his feet.", "twenty": "", "jps": "He pursueth them, and passeth on safely; the way with his feet he treadeth not.", "acv": "He pursues them, and passes on safely, even by a way that he had not gone with his feet.", "anderson": "", "haweis": "", "noyes": "He pursued them, and passed in safety, By a path which his foot had never trodden.", "webster": "He pursued them, [and] passed safely; [even] by the way [that] he had not gone with his feet.", "vulgate": "persequetur eos transibit in pace semita in pedibus eius non apparebit;", "brenton": "And he shall pursue them; the way of his feet shall proceed in peace."}}, {"v": 4, "ref": "41:4", "o": "מִֽי פָעַ֣ל וְ/עָשָׂ֔ה קֹרֵ֥א הַ/דֹּר֖וֹת מֵ/רֹ֑אשׁ אֲנִ֤י יְהוָה֙ רִאשׁ֔וֹן וְ/אֶת אַחֲרֹנִ֖ים אֲנִי הֽוּא", "en": {"kjv": "Who hath wrought and done it, calling the generations from the beginning? I the Lord, the first, and with the last; I am he.", "web": "Who has worked and done it, calling the generations from the beginning? I, Yahweh, the first, and with the last, I am he.”", "bsb": "Who has performed this and carried it out, calling forth the generations from the beginning? I, the LORD—the first and the last— I am He.”", "asv": "Who hath wrought and done it, calling the generations from the beginning? I, Jehovah, the first, and with the last, I am he.", "ylt": "Who hath wrought and done, Calling the generations from the first? I, Jehovah, the first, and with the last I am He.", "dra": "Who hath wrought and done these things, calling the generations from the beginning? I the Lord, I am the first and the last.", "bbe": "Whose purpose and work was it? His who sent out the generations from the start. I the Lord, the first, and with the last, I am he.", "geneva": "Who hath wrought and done it? he that calleth the generations from the beginning. I the Lord am the first, and with the last I am ye same.", "wycliffe": "Who wrouyte and dide these thingis? clepynge generaciouns at the bigynnyng. Y am the Lord; and Y am the firste and the laste.", "rotherham": "Who hath wrought and performed, Calling the generations, in advance? I, Yahweh, [who am] First, And with them who are last, I, am the Same!", "darby": "Who hath wrought and done [it], calling the generations from the beginning? I, Jehovah, the first; and with the last, I [am] HE.", "twenty": "", "jps": "Who hath wrought and done it? He that called the generations from the beginning. I, HaShem, who am the first, and with the last am the same.", "acv": "Who has wrought and done it, calling the generations from the beginning? I, Jehovah, the first, and with the last, I am he.", "anderson": "", "haweis": "", "noyes": "Who hath wrought and done it? I, who have called the generations from the beginning, I, Jehovah, the first; And with the last also am I.", "webster": "Who hath wrought and done [it], calling the generations from the beginning? I the LORD, the first, and with the last; I [am] he.", "vulgate": "quis haec operatus est et fecit vocans generationes ab exordio ego Dominus primus et novissimus ego sum;", "brenton": "Who has wrought and done these things? he has called it who called it from the generations of old; I God, the first and to all futurity, I AM."}}, {"v": 5, "ref": "41:5", "o": "רָא֤וּ אִיִּים֙ וְ/יִירָ֔אוּ קְצ֥וֹת הָ/אָ֖רֶץ יֶחֱרָ֑דוּ קָרְב֖וּ וַ/יֶּאֱתָיֽוּ/ן", "en": {"kjv": "The isles saw it, and feared; the ends of the earth were afraid, drew near, and came.", "web": "The islands have seen, and fear. The ends of the earth tremble. They approach, and come.", "bsb": "The islands see and fear; the ends of the earth tremble. They approach and come forward.", "asv": "The isles have seen, and fear; the ends of the earth tremble; they draw near, and come.", "ylt": "Seen have isles and fear, ends of the earth tremble, They have drawn near, yea, they come.", "dra": "The islands saw it, and feared, the ends of the earth were astonished, they drew near, and came.", "bbe": "The sea-lands saw it, and were in fear; the ends of the earth were shaking: they came near.", "geneva": "The yles sawe it, and did feare, and the ends of the earth were abashed, drew neere, and came.", "wycliffe": "Ilis sien, and dredden; the laste partis of erthe were astonyed; thei camen niy, and neiyiden.", "rotherham": "Coastlands have seen, so they fear, The ends of the earth, are in dread,—They have drawn near, and have come:", "darby": "The isles saw [it], and feared; the ends of the earth trembled: they drew near, and came.", "twenty": "", "jps": "The isles saw, and feared; the ends of the earth trembled; they drew near, and came.", "acv": "The isles have seen, and fear. The ends of the earth tremble, they draw near, and come.", "anderson": "", "haweis": "", "noyes": "Distant nations saw it, and were afraid; The ends of the earth, and trembled; They drew near, and came together.", "webster": "The isles saw [it], and feared; the ends of the earth were afraid, drew near, and came.", "vulgate": "viderunt insulae et timuerunt extrema terrae obstipuerunt adpropinquaverunt et accesserunt;", "brenton": "The nations saw, and feared; the ends of the earth drew nigh, and came together,"}}, {"v": 6, "ref": "41:6", "o": "אִ֥ישׁ אֶת רֵעֵ֖/הוּ יַעְזֹ֑רוּ וּ/לְ/אָחִ֖י/ו יֹאמַ֥ר חֲזָֽק", "en": {"kjv": "They helped every one his neighbour; and every one said to his brother, Be of good courage.", "web": "Everyone helps his neighbor. They say to their brothers, “Be strong!”", "bsb": "Each one helps the other and says to his brother, “Be strong!”", "asv": "They help every one his neighbor; and every one saith to his brother, Be of good courage.", "ylt": "Each his neighbour they help, And to his brother he saith, `Be strong.'", "dra": "Every one shall help his neighbour, and shall say to his brother: Be of good courage.", "bbe": "They gave help everyone to his neighbour; and everyone said to his brother, Take heart!", "geneva": "Euery man helped his neighbour, and saide to his brother, Be strong.", "wycliffe": "Ech man schal helpe his neiybore, and schal seie to his brother, Be thou coumfortid.", "rotherham": "Every man, to his neighbour, giveth help,—And to his brother, saith Take courage!", "darby": "They helped every one his neighbour, and [each] said to his brother, Take courage.", "twenty": "", "jps": "They helped every one his neighbour; and every one said to his brother: 'Be of good courage.'", "acv": "They help every man his neighbor, and says to his brother, Be of good courage.", "anderson": "", "haweis": "", "noyes": "One helped another, And said to him, \"Be of good courage!\"", "webster": "They helped every one his neighbor; and [every one] said to his brother, Be of good courage.", "vulgate": "unusquisque proximo suo auxiliatur et fratri suo dicit confortare;", "brenton": "every one judging for his neighbor and that to assist his brother: and one will say,"}}, {"v": 7, "ref": "41:7", "o": "וַ/יְחַזֵּ֤ק חָרָשׁ֙ אֶת צֹרֵ֔ף מַחֲלִ֥יק פַּטִּ֖ישׁ אֶת ה֣וֹלֶם פָּ֑עַם אֹמֵ֤ר לַ/דֶּ֨בֶק֙ ט֣וֹב ה֔וּא וַ/יְחַזְּקֵ֥/הוּ בְ/מַסְמְרִ֖ים לֹ֥א יִמּֽוֹט", "en": {"kjv": "So the carpenter encouraged the goldsmith, and he that smootheth with the hammer him that smote the anvil, saying, It is ready for the sodering: and he fastened it with nails, that it should not be moved.", "web": "So the carpenter encourages the goldsmith. He who smoothes with the hammer encourages him who strikes the anvil, saying of the soldering, “It is good”; and he fastens it with nails, that it might not totter.", "bsb": "The craftsman encourages the goldsmith, and he who wields the hammer cheers him who strikes the anvil, saying of the welding, “It is good.” He nails it down so it will not be toppled.", "asv": "So the carpenter encourageth the goldsmith, and he that smootheth with the hammer him that smiteth the anvil, saying of the soldering, It is good; and he fasteneth it with nails, that it should not be moved.", "ylt": "And strengthen doth an artisan the refiner, A smoother with a hammer, Him who is beating on an anvil, Saying, `For joining it is good,' And he strengtheneth it with nails, it is not moved!", "dra": "The coppersmith striking with the hammer encouraged him that forged at that time, saying: It is ready for soldering: and he strengthened it with nails, that it should not be moved.", "bbe": "So the metal-worker put heart into the gold-worker, and he who was hammering the metal smooth said kind words to the iron-worker, saying of the plate, It is ready: and he put it together with nails, so that there might be no slipping.", "geneva": "So the workeman comforted the founder, and he that smote with ye hammer, him that smote by course, saying, It is ready for the sodering, and he fastened it with nayles that it shoulde not be mooued.", "wycliffe": "A smyth of metal smytynge with an hamer coumfortide him that polischyde, ethir made fair, in that tyme, seiynge, It is good, to glu; and he fastenede hym with nailis, that he schulde not be mouyd.", "rotherham": "So, the carver, hath encouraged, the goldsmith, he that maketh smooth with the hammer, him that smiteth the anvil,—Saying of the welding, It is, good, Then hath he fastened it with nails—it must not totter!", "darby": "And the artizan encouraged the founder, he that smootheth [with] the hammer him that smiteth on the anvil, saying of the soldering, It is good; and he fasteneth it with nails, that it be not moved.", "twenty": "", "jps": "So the carpenter encouraged the goldsmith, and he that smootheth with the hammer him that smiteth the anvil, saying of the soldering: 'It is good'; and he fastened it with nails, that it should not be moved.", "acv": "So the carpenter encourages the goldsmith, he who smoothes with the hammer, him who smites the anvil, saying of the soldering, It is good, and he fastens it with nails, that it should not be moved.", "anderson": "", "haweis": "", "noyes": "The carpenter encouraged the smith, He that smoothed with the hammer him that smote on the anvil, And said, \"The soldering is good,\" And he fastened it with nails that it might not fall.", "webster": "So the carpenter encouraged the goldsmith, [and] he that smootheth [with] the hammer him that smote the anvil, saying, It [is] ready for the sodering: and he fastened it with nails, [that] it should not be moved.", "vulgate": "confortabit faber aerarius percutiens malleo eum qui cudebat tunc temporis dicens glutino bonum est et confortavit eum in clavis ut non moveatur;", "brenton": "The artificer has become strong, and the coppersmith that smites with the hammer, and forges also: sometimes he will say, It is a piece well joined: they have fastened them with nails; they will fix them, and they shall not be moved."}}, {"v": 8, "ref": "41:8", "o": "וְ/אַתָּה֙ יִשְׂרָאֵ֣ל עַבְדִּ֔/י יַעֲקֹ֖ב אֲשֶׁ֣ר בְּחַרְתִּ֑י/ךָ זֶ֖רַע אַבְרָהָ֥ם אֹהֲבִֽ/י", "en": {"kjv": "But thou, Israel, art my servant, Jacob whom I have chosen, the seed of Abraham my friend.", "web": "“But you, Israel, my servant, Jacob whom I have chosen, the seed of Abraham my friend,", "bsb": "“But you, O Israel, My servant, Jacob, whom I have chosen, descendant of Abraham My friend—", "asv": "But thou, Israel, my servant, Jacob whom I have chosen, the seed of Abraham my friend,", "ylt": "--And thou, O Israel, My servant, Jacob, whom I have chosen, Seed of Abraham, My lover,", "dra": "But thou Israel, art my servant, Jacob whom I have chosen, the seed of Abraham my friend:", "bbe": "But as for you, Israel, my servant, and you, Jacob, whom I have taken for myself, the seed of Abraham my friend:", "geneva": "But thou, Israel, art my seruant, and thou Iaakob, whom I haue chosen, the seede of Abraham my friend.", "wycliffe": "And thou, Israel, my seruaunte, Jacob, whom Y chees, the seed of Abraham, my frend, in whom Y took thee;", "rotherham": "But, thou, Israel, my Servant, Jacob whom I have chosen,—The seed of Abraham my loving one;", "darby": "But thou, Israel, my servant, Jacob, whom I have chosen, the seed of Abraham, my friend", "twenty": "", "jps": "But thou, Israel, My servant, Jacob whom I have chosen, the seed of Abraham My friend;", "acv": "But thou, Israel, my servant, Jacob whom I have chosen, the seed of Abraham my friend,", "anderson": "", "haweis": "", "noyes": "But thou, O Israel, my servant, Thou, Jacob, whom I have chosen, Offspring of Abraham, my friend!", "webster": "But thou, Israel, [art] my servant, Jacob whom I have chosen, the seed of Abraham my friend.", "vulgate": "et tu Israhel serve meus Iacob quem elegi semen Abraham amici mei;", "brenton": "But thou, Israel, art my servant Jacob, and he whom I have chosen, the seed of Abraam, whom I have loved:"}}, {"v": 9, "ref": "41:9", "o": "אֲשֶׁ֤ר הֶחֱזַקְתִּ֨י/ךָ֙ מִ/קְצ֣וֹת הָ/אָ֔רֶץ וּ/מֵ/אֲצִילֶ֖י/הָ קְרָאתִ֑י/ךָ וָ/אֹ֤מַר לְ/ךָ֙ עַבְדִּ/י אַ֔תָּה בְּחַרְתִּ֖י/ךָ וְ/לֹ֥א מְאַסְתִּֽי/ךָ", "en": {"kjv": "Thou whom I have taken from the ends of the earth, and called thee from the chief men thereof, and said unto thee, Thou art my servant; I have chosen thee, and not cast thee away.", "web": "You whom I have taken hold of from the ends of the earth, and called from its corners, and said to you, ‘You are my servant, I have chosen you and not cast you away;’", "bsb": "I brought you from the ends of the earth and called you from its farthest corners. I said, ‘You are My servant.’ I have chosen and not rejected you.", "asv": "thou whom I have taken hold of from the ends of the earth, and called from the corners thereof, and said unto thee, Thou art my servant, I have chosen thee and not cast thee away;", "ylt": "Whom I have taken hold of, from the ends of the earth, And from its near places I have called thee, And I say to thee, My servant Thou art , I have chosen thee, and not rejected thee.", "dra": "In whom I have taken thee from the ends of the earth, and from the remote parts thereof have called thee, and said to thee: Thou art my servant, I have chosen thee, and have not cast thee away.", "bbe": "You whom I have taken from the ends of the earth, and sent for from its farthest parts, saying to you, You are my servant, whom I have taken for myself, and whom I have not given up:", "geneva": "For I haue taken thee from the endes of the earth, and called thee before the chiefe thereof, and saide vnto thee, Thou art my seruant: I haue chosen thee, and not cast thee away.", "wycliffe": "fro the laste partis of erthe, and fro the fer partis therof Y clepide thee; and Y seide to thee, Thou art my seruaunt; Y chees thee, and castide not awei thee.", "rotherham": "Thou whom I have taken hold of from the ends of the earth, And from the extremities thereof, have called thee,—And said to thee, My Servant, thou! I have chosen thee and not cast thee off,", "darby": "— thou whom I have taken from the ends of the earth, and called from the extremities thereof, and to whom I said, Thou art my servant, I have chosen thee and not rejected thee,", "twenty": "", "jps": "Thou whom I have taken hold of from the ends of the earth, and called thee from the uttermost parts thereof, and said unto thee: 'Thou art My servant, I have chosen thee and not cast thee away';", "acv": "thou whom I have taken hold of from the ends of the earth, and called from the corners thereof, and said to thee, Thou are my servant, I have chosen thee and not cast thee away.", "anderson": "", "haweis": "", "noyes": "Thou, whom I have led by the hand from the ends of the earth, And called from the extremities thereof, And said to thee, \"Thou art my servant, I have chosen thee, and not cast thee away!\"", "webster": "[Thou] whom I have taken from the ends of the earth, and called thee from the chief men thereof, and said to thee, Thou [art] my servant; I have chosen thee, and not cast thee away.", "vulgate": "in quo adprehendi te ab extremis terrae et a longinquis eius vocavi te et dixi tibi servus meus es tu elegi te et non abieci te;", "brenton": "whom I have taken hold of from the ends of the earth, and from the high places of it I have called thee, and said to thee, Thou art my servant; I have chosen thee, and I have not forsaken thee."}}, {"v": 10, "ref": "41:10", "o": "אַל תִּירָא֙ כִּ֣י עִמְּ/ךָ אָ֔נִי אַל תִּשְׁתָּ֖ע כִּֽי אֲנִ֣י אֱלֹהֶ֑י/ךָ אִמַּצְתִּ֨י/ךָ֙ אַף עֲזַרְתִּ֔י/ךָ אַף תְּמַכְתִּ֖י/ךָ בִּ/ימִ֥ין צִדְקִֽ/י", "en": {"kjv": "Fear thou not; for I am with thee: be not dismayed; for I am thy God: I will strengthen thee; yea, I will help thee; yea, I will uphold thee with the right hand of my righteousness.", "web": "Don’t you be afraid, for I am with you. Don’t be dismayed, for I am your God. I will strengthen you. Yes, I will help you. Yes, I will uphold you with the right hand of my righteousness.", "bsb": "Do not fear, for I am with you; do not be afraid, for I am your God. I will strengthen you; I will surely help you; I will uphold you with My right hand of righteousness.", "asv": "fear thou not, for I am with thee; be not dismayed, for I am thy God; I will strengthen thee; yea, I will help thee; yea, I will uphold thee with the right hand of my righteousness.", "ylt": "Be not afraid, for with thee I am , Look not around, for I am thy God, I have strengthened thee, Yea, I have helped thee, yea, I upheld thee, With the right hand of My righteousness.", "dra": "Fear not, for I am with thee: turn not aside, for I am thy God: I have strengthened thee, and have helped thee, and the right hand of my just one hath upheld thee.", "bbe": "Have no fear, for I am with you; do not be looking about in trouble, for I am your God; I will give you strength, yes, I will be your helper; yes, my true right hand will be your support.", "geneva": "Feare thou not, for I am with thee: be not afraide, for I am thy God: I will strengthen thee, and helpe thee, and will susteine thee with the right hand of my iustice.", "wycliffe": "Drede thou not, for Y am with thee; boowe thou not awei, for Y am thi God. Y coumfortide thee, and helpide thee; and the riythond of my iust man vp took thee.", "rotherham": "Do not fear, for with thee, I am! Look not around, for, I, am thy God,—I have emboldened thee, Yea I have helped thee, Yea I have upheld thee with my righteous right-hand.", "darby": "— Fear not, for I [am] with thee; be not dismayed, for I [am] thyGod: I will strengthen thee, yea, I will help thee, yea, I will uphold thee with the right hand of my righteousness.", "twenty": "", "jps": "Fear thou not, for I am with thee, be not dismayed, for I am thy G-d; I strengthen thee, yea, I help thee; yea, I uphold thee with My victorious right hand.", "acv": "Fear thou not, for I am with thee. Be not dismayed, for I am thy God. I will strengthen thee. Yea, I will help thee. Yea, I will uphold thee with the right hand of my righteousness.", "anderson": "", "haweis": "", "noyes": "Fear not, for I am with thee; Faint not, for I, thy God, will strengthen thee; I will help thee, and sustain thee, with my right hand of salvation!", "webster": "Fear thou not; for I [am] with thee: be not dismayed; for I [am] thy God: I will strengthen thee; yes, I will help thee; yes, I will uphold thee with the right hand of my righteousness.", "vulgate": "ne timeas quia tecum sum ego ne declines quia ego Deus tuus confortavi te et auxiliatus sum tui et suscepi te dextera iusti mei;", "brenton": "Fear not; for I am with thee: wander not; for I am thy God, who have strengthened thee; and I have helped thee, and have established thee with my just right hand."}}, {"v": 11, "ref": "41:11", "o": "הֵ֤ן יֵבֹ֨שׁוּ֙ וְ/יִכָּ֣לְמ֔וּ כֹּ֖ל הַ/נֶּחֱרִ֣ים בָּ֑/ךְ יִֽהְי֥וּ כְ/אַ֛יִן וְ/יֹאבְד֖וּ אַנְשֵׁ֥י רִיבֶֽ/ךָ", "en": {"kjv": "Behold, all they that were incensed against thee shall be ashamed and confounded: they shall be as nothing; and they that strive with thee shall perish.", "web": "Behold, all those who are incensed against you will be disappointed and confounded. Those who strive with you will be like nothing, and shall perish.", "bsb": "Behold, all who rage against you will be ashamed and disgraced; those who contend with you will be reduced to nothing and will perish.", "asv": "Behold, all they that are incensed against thee shall be put to shame and confounded: they that strive with thee shall be as nothing, and shall perish.", "ylt": "Lo, all those displeased with thee, They are ashamed and blush, They are as nothing, yea, perish Do the men who strive with thee.", "dra": "Behold all that fight against thee shall be confounded and ashamed, they shall be as nothing, and the men shall perish that strive against thee.", "bbe": "Truly, all those who are angry with you will be made low and put to shame: those desiring to do you wrong will come to nothing and never again be seen.", "geneva": "Beholde, all they that prouoke thee, shalbe ashamed, and confounded: they shalbe as nothing, and they that striue with thee, shall perish.", "wycliffe": "Lo! alle men schulen be schent, and schulen be aschamed, that fiyten ayens thee; thei schulen be as if thei ben not, and men schulen perische, that ayen seien thee.", "rotherham": "Lo! they shall turn pale and be ashamed—All they who have been incensed against thee,—They shall become as nothing and perish—The men who have been thine accusers:", "darby": "Lo, all that are incensed against thee shall be ashamed and confounded; they that strive with thee shall be as nothing, and shall perish.", "twenty": "", "jps": "Behold, all they that were incensed against thee shall be ashamed and confounded; they that strove with thee shall be as nothing, and shall perish.", "acv": "Behold, all those who are incensed against thee shall be put to shame and confounded. Those who strive with thee shall be as nothing, and shall perish.", "anderson": "", "haweis": "", "noyes": "Behold, all who are enraged against thee Shall be ashamed and confounded; All that contend with thee Shall come to nothing and perish.", "webster": "Behold, all [they that were] incensed against thee shall be ashamed and confounded: they shall be as nothing; and they that contend with thee shall perish.", "vulgate": "ecce confundentur et erubescent omnes qui pugnant adversum te erunt quasi non sint et peribunt viri qui contradicunt tibi;", "brenton": "Behold, all thine adversaries shall be ashamed and confounded; for they shall be as if they were not: and all thine opponents shall perish."}}, {"v": 12, "ref": "41:12", "o": "תְּבַקְשֵׁ/ם֙ וְ/לֹ֣א תִמְצָאֵ֔/ם אַנְשֵׁ֖י מַצֻּתֶ֑/ךָ יִהְי֥וּ כְ/אַ֛יִן וּ/כְ/אֶ֖פֶס אַנְשֵׁ֥י מִלְחַמְתֶּֽ/ךָ", "en": {"kjv": "Thou shalt seek them, and shalt not find them, even them that contended with thee: they that war against thee shall be as nothing, and as a thing of nought.", "web": "You will seek them, and won’t find them, even those who contend with you. Those who war against you will be as nothing, as a non-existent thing.", "bsb": "You will seek them but will not find them. Those who wage war against you will come to nothing.", "asv": "Thou shalt seek them, and shalt not find them, even them that contend with thee: they that war against thee shall be as nothing, and as a thing of nought.", "ylt": "Thou seekest them, and findest them not, The men who debate with thee, They are as nothing, yea, as nothing, The men who war with thee.", "dra": "Thou shalt seek them, and shalt not find the men that resist thee: they shall be as nothing: and as a thing consumed the men that war against thee.", "bbe": "You will make search for your haters but they will not be there; those who make war against you will be as nothing and will come to destruction.", "geneva": "Thou shalt seeke them and shalt not finde them: to wit, the men of thy strife, for they shall be as nothing, and the men that warre against thee, as a thing of nought.", "wycliffe": "Thou schalt seke hem, and thou schalt not fynde thi rebel men; thei schulen be, as if thei ben not, and as the wastyng of a man fiytynge ayens thee.", "rotherham": "Thou shalt seek them, but shalt not find them—The men who have contended with thee, They shall become as nothing, and as a thing of nought—The men who have warred against thee;", "darby": "Thou shalt seek them, and shalt not find them — them that contend with thee; they that war against thee shall be as nothing, and as a thing of nought.", "twenty": "", "jps": "Thou shalt seek them, and shalt not find them, even them that contended with thee; they that warred against thee shall be as nothing, and as a thing of nought.", "acv": "Thou shall seek them, and shall not find them, even those who contend with thee. Those who war against thee shall be as nothing, and as a thing of naught.", "anderson": "", "haweis": "", "noyes": "Thou shalt seek and not find Them that contend with thee; They shall come to nothing, and be no more, Who make war against thee.", "webster": "Thou shalt seek them, and shalt not find them, [even] them that contended with thee: they that war against thee shall be as nothing, and as a thing of naught.", "vulgate": "quaeres eos et non invenies viros rebelles tuos erunt quasi non sint et veluti consumptio homines bellantes adversum te;", "brenton": "Thou shalt seek them, and thou shalt not find the men who shall insolently rage against thee: for they shall be as if they were not, and they that war against thee shall not be."}}, {"v": 13, "ref": "41:13", "o": "כִּ֗י אֲנִ֛י יְהוָ֥ה אֱלֹהֶ֖י/ךָ מַחֲזִ֣יק יְמִינֶ֑/ךָ הָ/אֹמֵ֥ר לְ/ךָ֛ אַל תִּירָ֖א אֲנִ֥י עֲזַרְתִּֽי/ךָ", "en": {"kjv": "For I the Lord thy God will hold thy right hand, saying unto thee, Fear not; I will help thee.", "web": "For I, Yahweh your God, will hold your right hand, saying to you, ‘Don’t be afraid. I will help you.’", "bsb": "For I am the LORD your God, who takes hold of your right hand and tells you: Do not fear, I will help you.", "asv": "For I, Jehovah thy God, will hold thy right hand, saying unto thee, Fear not; I will help thee.", "ylt": "For I, Jehovah thy God, Am strengthening thy right hand, He who is saying to thee, `Fear not, I have helped thee.'", "dra": "For I am the Lord thy God, who take thee by the hand, and say to thee: Fear not, I have helped thee.", "bbe": "For I, the Lord your God, have taken your right hand in mine, saying to you, Have no fear; I will be your helper.", "geneva": "For I the Lord thy God will hold thy right hand, saying vnto thee, Feare not, I wil helpe thee.", "wycliffe": "For Y am thi Lord God, takynge thin hond, and seiynge to thee, Drede thou not, Y helpide thee.", "rotherham": "For I, Yahweh thy God am firmly grasping thy right-hand,—Who am saying unto thee Do not fear! I, have become thy helper!", "darby": "For I, Jehovah, thyGod, hold thy right hand, saying unto thee, Fear not; I will help thee.", "twenty": "", "jps": "For I HaShem thy G-d hold thy right hand, who say unto thee: 'Fear not, I help thee.'", "acv": "For I, Jehovah thy God, will hold thy right hand, saying to thee, Fear not, I will help thee.", "anderson": "", "haweis": "", "noyes": "For I, Jehovah, am thy God, that holdeth thee by the right hand, That saith to thee, \"Fear not, I am thy helper!\"", "webster": "For I the LORD thy God will hold thy right hand, saying to thee, Fear not; I will help thee.", "vulgate": "quia ego Dominus Deus tuus adprehendens manum tuam dicensque tibi ne timeas ego adiuvi te;", "brenton": "For I am thy God, who holdeth thy right hand, who saith to thee,"}}, {"v": 14, "ref": "41:14", "o": "אַל תִּֽירְאִי֙ תּוֹלַ֣עַת יַֽעֲקֹ֔ב מְתֵ֖י יִשְׂרָאֵ֑ל אֲנִ֤י עֲזַרְתִּי/ךְ֙ נְאֻם יְהוָ֔ה וְ/גֹאֲלֵ֖/ךְ קְד֥וֹשׁ יִשְׂרָאֵֽל", "en": {"kjv": "Fear not, thou worm Jacob, and ye men of Israel; I will help thee, saith the Lord, and thy redeemer, the Holy One of Israel.", "web": "Don’t be afraid, you worm Jacob, and you men of Israel. I will help you,” says Yahweh, “and your Redeemer is the Holy One of Israel.", "bsb": "Do not fear, O worm of Jacob, O few men of Israel. I will help you,” declares the LORD. “Your Redeemer is the Holy One of Israel.", "asv": "Fear not, thou worm Jacob, and ye men of Israel; I will help thee, saith Jehovah, and thy Redeemer is the Holy One of Israel.", "ylt": "Fear not, O worm Jacob, ye men of Israel, I helped thee, an affirmation of Jehovah, Even thy redeemer, the Holy One of Israel.", "dra": "Fear not, thou worm of Jacob, you that are dead of Israel: I have helped thee, saith the Lord: and thy Redeemer the Holy One of Israel.", "bbe": "Have no fear, you worm Jacob, and you men of Israel; I will be your helper, says the Lord, even he who takes up your cause, the Holy One of Israel.", "geneva": "Feare not, thou worme, Iaakob, and ye men of Israel: I wil helpe thee, sayth the Lord and thy redeemer the holy one of Israel.", "wycliffe": "Nyle thou, worm of Jacob, drede, ye that ben deed of Israel. Y helpide thee, seith the Lord, and thin ayen biere, the hooli of Israel.", "rotherham": "Do not fear, Thou worm Jacob, Ye men of Israel,—I, have become thy helper, Declareth Yahweh, And thy redeemer The Holy One of Israel.", "darby": "Fear not, thou worm Jacob, ye men of Israel; I will help thee, saith Jehovah, and thy Redeemer, the Holy One of Israel.", "twenty": "", "jps": "Fear not, thou worm Jacob, and ye men of Israel; I help thee, saith HaShem, and thy Redeemer, the Holy One of Israel.", "acv": "Fear not, thou worm Jacob, and ye men of Israel. I will help thee, says Jehovah, and thy Redeemer is the Holy One of Israel.", "anderson": "", "haweis": "", "noyes": "Fear not, thou worm Jacob, thou feeble people of Israel! I am thy helper, saith Jehovah; Thy redeemer is the Holy One of Israel.", "webster": "Fear not, thou worm Jacob, [and] ye men of Israel; I will help thee, saith the LORD, and thy Redeemer, the Holy One of Israel.", "vulgate": "noli timere vermis Iacob qui mortui estis ex Israhel ego auxiliatus sum tui dicit Dominus et redemptor tuus Sanctus Israhel;", "brenton": "Fear not, Jacob, and thou Israel few in number; I have helped thee, saith thy God, he that redeems thee, O Israel."}}, {"v": 15, "ref": "41:15", "o": "הִנֵּ֣ה שַׂמְתִּ֗י/ךְ לְ/מוֹרַג֙ חָר֣וּץ חָדָ֔שׁ בַּ֖עַל פִּֽיפִיּ֑וֹת תָּד֤וּשׁ הָרִים֙ וְ/תָדֹ֔ק וּ/גְבָע֖וֹת כַּ/מֹּ֥ץ תָּשִֽׂים", "en": {"kjv": "Behold, I will make thee a new sharp threshing instrument having teeth: thou shalt thresh the mountains, and beat them small, and shalt make the hills as chaff.", "web": "Behold, I have made you into a new sharp threshing instrument with teeth. You will thresh the mountains, and beat them small, and will make the hills like chaff.", "bsb": "Behold, I will make you into a threshing sledge, new and sharp, with many teeth. You will thresh the mountains and crush them, and reduce the hills to chaff.", "asv": "Behold, I have made thee to be a new sharp threshing instrument having teeth; thou shalt thresh the mountains, and beat them small, and shalt make the hills as chaff.", "ylt": "Lo, I have set thee for a new sharp threshing instrument, Possessing teeth, thou threshest mountains, And beatest small, and hills as chaff thou makest.", "dra": "I have made thee as a new thrashing wain, with teeth like a saw: thou shalt thrash the mountains, and break them in pieces: and shalt make the hills as chaff.", "bbe": "See, I will make you like a new grain-crushing instrument with teeth, crushing the mountains small, and making the hills like dry stems.", "geneva": "Behold, I wil make thee a roller, and a newe threshing instrument hauing teeth: thou shalt thresh the mountaines, and bring them to pouder, and shalt make the hilles as chaffe.", "wycliffe": "Y haue set thee as a newe wayn threischynge, hauynge sawynge bilis; thou schalt threische mounteyns, and schalt make smal, and thou schalt sette litle hillis as dust.", "rotherham": "Lo! I have made of thee a new pointed threshing sledge, owning teeth,—Thou shalt thresh mountains and crush them, And, hills—like chaff, shalt thou make:", "darby": "Behold, I have made of thee a new sharp threshing instrument having double teeth: thou shalt thresh and beat small the mountains, and shalt make the hills as chaff;", "twenty": "", "jps": "Behold, I make thee a new threshing-sledge having sharp teeth; thou shalt thresh the mountains, and beat them small, and shalt make the hills as chaff.", "acv": "Behold, I have made thee as a new sharp threshing instrument having teeth. Thou shall thresh the mountains, and beat them small, and shall make the hills as chaff.", "anderson": "", "haweis": "", "noyes": "Behold, I will make thee a thrashing-wain, sharp and new, With double edges; Thou shalt thrash the mountains, and beat them small, And make the hills as chaff.", "webster": "Behold, I will make thee a new sharp threshing instrument having teeth: thou shalt thresh the mountains, and beat [them] small, and shalt make the hills as chaff.", "vulgate": "ego posui te quasi plaustrum triturans novum habens rostra serrantia triturabis montes et comminues et colles quasi pulverem pones;", "brenton": "Behold, I have made thee as new saw-shaped threshing wheels of a waggon; and thou shalt thresh the mountains, and beat the hills to powder, and make them as chaff:"}}, {"v": 16, "ref": "41:16", "o": "תִּזְרֵ/ם֙ וְ/ר֣וּחַ תִּשָּׂאֵ֔/ם וּ/סְעָרָ֖ה תָּפִ֣יץ אוֹתָ֑/ם וְ/אַתָּה֙ תָּגִ֣יל בַּֽ/יהוָ֔ה בִּ/קְד֥וֹשׁ יִשְׂרָאֵ֖ל תִּתְהַלָּֽל", "en": {"kjv": "Thou shalt fan them, and the wind shall carry them away, and the whirlwind shall scatter them: and thou shalt rejoice in the Lord, and shalt glory in the Holy One of Israel.", "web": "You will winnow them, and the wind will carry them away, and the whirlwind will scatter them. You will rejoice in Yahweh. You will glory in the Holy One of Israel.", "bsb": "You will winnow them, and a wind will carry them away; a gale will scatter them. But you will rejoice in the LORD; you will glory in the Holy One of Israel.", "asv": "Thou shalt winnow them, and the wind shall carry them away, and the whirlwind shall scatter them; and thou shalt rejoice in Jehovah, thou shalt glory in the Holy One of Israel.", "ylt": "Thou winnowest them, and a wind lifteth them up, And a whirlwind scattereth them, And thou--thou rejoicest in Jehovah, In the Holy One of Israel dost boast thyself.", "dra": "Thou shalt fan them, and the wind shall carry them away, and the whirlwind shall scatter them: and thou shalt rejoice in the Lord, in the Holy One of Israel thou shalt be joyful.", "bbe": "You will send the wind over them, and it will take them away; they will go in all directions before the storm-wind: you will have joy in the Lord, and be glad in the Holy One of Israel.", "geneva": "Thou shalt fanne them, and the winde shall carie them away, and the whirlewinde shall scatter them: and thou shalt reioyce in the Lord, and shalt glory in the holy one of Israel.", "wycliffe": "Thou schalt wyndewe hem, and the wynd schal take hem awei, and a whirlewynd schal scatere hem; and thou schalt make ful out ioie in the Lord, and thou schalt be glad in the hooli of Israel.", "rotherham": "Thou shalt fan them and, a wind, shall carry them away, And, a whirlwind, scatter, them,—But, thou, shalt exult in Yahweh, And, in the Holy One of Israel, shalt thou boast thyself.", "darby": "thou shalt fan them, and the wind shall carry them away, and the whirlwind shall scatter them; and thou shalt rejoice in Jehovah, thou shalt glory in the Holy One of Israel.", "twenty": "", "jps": "Thou shalt fan them, and the wind shall carry them away, and the whirlwind shall scatter them; and thou shalt rejoice in HaShem, thou shalt glory in the Holy One of Israel.", "acv": "Thou shall winnow them, and the wind shall carry them away, and the whirlwind shall scatter them. And thou shall rejoice in Jehovah. Thou shall glory in the Holy One of Israel.", "anderson": "", "haweis": "", "noyes": "Thou shalt winnow them, and the wind shall carry them away, And the whirlwind shall scatter them. But thou shalt rejoice in Jehovah, And glory in the Holy One of Israel.", "webster": "Thou shalt fan them, and the wind shall carry them away, and the whirlwind shall scatter them: and thou shalt rejoice in the LORD, [and] shalt glory in the Holy One of Israel.", "vulgate": "ventilabis eos et ventus tollet et turbo disperget eos et tu exultabis in Domino in Sancto Israhel laetaberis;", "brenton": "and thou shalt winnow them, and the wind shall carry them away, and a tempest shall scatter them: but thou shalt rejoice in the holy ones of Israel."}}, {"v": 17, "ref": "41:17", "o": "הָ/עֲנִיִּ֨ים וְ/הָ/אֶבְיוֹנִ֜ים מְבַקְשִׁ֥ים מַ֨יִם֙ וָ/אַ֔יִן לְשׁוֹנָ֖/ם בַּ/צָּמָ֣א נָשָׁ֑תָּה אֲנִ֤י יְהוָה֙ אֶעֱנֵ֔/ם אֱלֹהֵ֥י יִשְׂרָאֵ֖ל לֹ֥א אֶעֶזְבֵֽ/ם", "en": {"kjv": "When the poor and needy seek water, and there is none, and their tongue faileth for thirst, I the Lord will hear them, I the God of Israel will not forsake them.", "web": "The poor and needy seek water, and there is none. Their tongue fails for thirst. I, Yahweh, will answer them. I, the God of Israel, will not forsake them.", "bsb": "The poor and needy seek water, but there is none; their tongues are parched with thirst. I, the LORD, will answer them; I, the God of Israel, will not forsake them.", "asv": "The poor and needy seek water, and there is none, and their tongue faileth for thirst; I, Jehovah, will answer them, I, the God of Israel, will not forsake them.", "ylt": "The poor and the needy are seeking water, And there is none, Their tongue with thirst hath failed, I, Jehovah do answer them, The God of Israel--I forsake them not.", "dra": "The needy and the poor seek for waters, and there are none: their tongue hath been dry with thirst. I the Lord will hear them, I the God of Israel will not forsake them.", "bbe": "The poor and crushed are looking for water where no water is, and their tongue is dry for need of it: I the Lord will give ear to their prayer, I the God of Israel will not give them up.", "geneva": "When the poore and the needy seeke water, and there is none (their tongue faileth for thirst: I the Lord will heare them: I the God of Israel will not forsake them)", "wycliffe": "Nedi men and pore seken watris, and tho ben not; the tunge of hem driede for thirst. Y the Lord schal here hem, I God of Israel schal not forsake hem.", "rotherham": "As for the oppressed and the needy. Seeking water when there is none, Their tongue with thirst being parched I—Yahweh, will answer them, The God of Israel, I will not forsake them:", "darby": "The afflicted and the needy seek water, and there is none; their tongue faileth for thirst: I, Jehovah, will answer them, [I], theGod of Israel, will not forsake them.", "twenty": "", "jps": "The poor and needy seek water and there is none, and their tongue faileth for thirst; I HaShem will answer them, I the G-d of Israel will not forsake them.", "acv": "The poor and needy seek water, and there is none, and their tongue fails for thirst. I, Jehovah, will answer them. I, the God of Israel, will not forsake them.", "anderson": "", "haweis": "", "noyes": "When the poor and needy seek water, and there is none, And their tongue is parched with thirst, I, Jehovah, will hear them; I, the God of Israel, will not forsake them.", "webster": "[When] the poor and needy seek water, and [there is] none, [and] their tongue faileth for thirst, I the LORD will hear them, [I] the God of Israel will not forsake them.", "vulgate": "egeni et pauperes quaerunt aquas et non sunt lingua eorum siti aruit ego Dominus exaudiam eos Deus Israhel non derelinquam eos;", "brenton": "And the poor and the needy shall exult; for when they shall seek water, and there shall be none, and their tongue is parched with thirst, I the Lord God, I the God of Israel will hear, and will not forsake them:"}}, {"v": 18, "ref": "41:18", "o": "אֶפְתַּ֤ח עַל שְׁפָיִים֙ נְהָר֔וֹת וּ/בְ/ת֥וֹךְ בְּקָע֖וֹת מַעְיָנ֑וֹת אָשִׂ֤ים מִדְבָּר֙ לַ/אֲגַם מַ֔יִם וְ/אֶ֥רֶץ צִיָּ֖ה לְ/מוֹצָ֥אֵי מָֽיִם", "en": {"kjv": "I will open rivers in high places, and fountains in the midst of the valleys: I will make the wilderness a pool of water, and the dry land springs of water.", "web": "I will open rivers on the bare heights, and springs in the midst of the valleys. I will make the wilderness a pool of water, and the dry land springs of water.", "bsb": "I will open rivers on the barren heights, and fountains in the middle of the valleys. I will turn the desert into a pool of water, and the dry land into flowing springs.", "asv": "I will open rivers on the bare heights, and fountains in the midst of the valleys; I will make the wilderness a pool of water, and the dry land springs of water.", "ylt": "I open on high places rivers, And in midst of valleys fountains, I make a wilderness become a pond of water, And a dry land become springs of water.", "dra": "I will open rivers in the high hills, and fountains in the midst of the plains: I will turn the desert into pools of waters, and the impassable land into streams of waters.", "bbe": "I will make rivers on the dry mountain-tops, and fountains in the valleys: I will make the waste land a pool of water, and the dry land springs of water.", "geneva": "I will open riuers in the toppes of the hils, and fountaines in the middes of the valleis: I will make the wildernesse as a poole of water, and the waste land as springs of water.", "wycliffe": "Y schal opene floodis in hiy hillis, and wellis in the myddis of feeldis; Y schal sette the desert in to poondis of watris, and the lond without weie in to ryuers of watris.", "rotherham": "I will open, On bare hills rivers, and In the midst of plains, fountains,—I will make The desert, a lake of water, and Parched land, springs of water;", "darby": "I will open rivers on the bare heights, and fountains in the midst of the valleys; I will make the wilderness into a pool of water, and the dry land into water-springs.", "twenty": "", "jps": "I will open rivers on the high hills, and fountains in the midst of the valleys; I will make the wilderness a pool of water, and the dry land springs of water.", "acv": "I will open rivers on the bare heights, and fountains in the midst of the valleys. I will make the wilderness a pool of water, and the dry land springs of water.", "anderson": "", "haweis": "", "noyes": "I will open rivers upon the bare hills, And fountains in the midst of the valleys; I will make the wilderness a pool of water, And the dry land springs of water.", "webster": "I will open rivers in high places, and fountains in the midst of the valleys: I will make the wilderness a pool of water, and the dry land springs of water.", "vulgate": "aperiam in supinis collibus flumina et in medio camporum fontes ponam desertum in stagna aquarum et terram inviam in rivos aquarum;", "brenton": "but I will open rivers on the mountains, and fountains in the midst of plains: I will make the desert pools of water, and a thirsty land watercourses."}}, {"v": 19, "ref": "41:19", "o": "אֶתֵּ֤ן בַּ/מִּדְבָּר֙ אֶ֣רֶז שִׁטָּ֔ה וַ/הֲדַ֖ס וְ/עֵ֣ץ שָׁ֑מֶן אָשִׂ֣ים בָּ/עֲרָבָ֗ה בְּר֛וֹשׁ תִּדְהָ֥ר וּ/תְאַשּׁ֖וּר יַחְדָּֽו", "en": {"kjv": "I will plant in the wilderness the cedar, the shittah tree, and the myrtle, and the oil tree; I will set in the desert the fir tree, and the pine, and the box tree together:", "web": "I will put cedar, acacia, myrtle, and oil trees in the wilderness. I will set fir trees, pine, and box trees together in the desert;", "bsb": "I will plant cedars in the wilderness, acacias, myrtles, and olive trees. I will set cypresses in the desert, elms and boxwood together,", "asv": "I will put in the wilderness the cedar, the acacia, and the myrtle, and the oil-tree; I will set in the desert the fir-tree, the pine, and the box-tree together:", "ylt": "I give in a wilderness the cedar, Shittah, and myrtle, and oil-tree, I set in a desert the fir-pine and box-wood together.", "dra": "I will plant in the wilderness the cedar, and the thorn, and the myrtle, and the olive tree: I will set in the desert the fir tree, the elm, and the box tree together:", "bbe": "I will put in the waste land the cedar, the acacia, the myrtle, and the olive-tree; and in the lowland will be planted the fir-tree, the plane, and the cypress together:", "geneva": "I will set in the wildernesse the cedar, the shittah tree, and the mirre tree, and the pine tree, and I will set in the wildernesse the firre tree, the elme and the boxe tree together.", "wycliffe": "Y schal yyue in wildirnesse a cedre, and a thorn, and a myrte tre, and the tre of an olyue; Y schal sette in the desert a fir tre, an elm, and a box tre togidere.", "rotherham": "I will set in the desert! Cedar, acacia, and myrtle, and oil-tree,—I will place, in the waste plain, Cypress, holm-oak, and sherbin-cedar, together", "darby": "I will give in the wilderness the cedar, acacia, myrtle, and oleaster; I will set in the desert the cypress, pine, and box-tree together;", "twenty": "", "jps": "I will plant in the wilderness the cedar, the acacia-tree, and the myrtle, and the oil-tree; I will set in the desert the cypress, the plane-tree, and the larch together;", "acv": "I will put in the wilderness the cedar, the acacia, and the myrtle, and the oil tree. I will set in the desert the fir tree, the pine, and the box tree together,", "anderson": "", "haweis": "", "noyes": "I will plant in the wilderness the cedar and the acacia, The myrtle and the olive-tree; I will place in the desert the cypress, The plane-tree and the larch together.", "webster": "I will plant in the wilderness the cedar, the shittah-tree, and the myrtle, and the oil-tree; I will set in the desert the fir-tree, the pine, and the box-tree together:", "vulgate": "dabo in solitudine cedrum et spinam et myrtum et lignum olivae ponam in deserto abietem ulmum et buxum simul;", "brenton": "I will plant in the dry land the cedar and box, the myrtle and cypress, and white poplar:"}}, {"v": 20, "ref": "41:20", "o": "לְמַ֧עַן יִרְא֣וּ וְ/יֵדְע֗וּ וְ/יָשִׂ֤ימוּ וְ/יַשְׂכִּ֨ילוּ֙ יַחְדָּ֔ו כִּ֥י יַד יְהוָ֖ה עָ֣שְׂתָה זֹּ֑את וּ/קְד֥וֹשׁ יִשְׂרָאֵ֖ל בְּרָאָֽ/הּ", "en": {"kjv": "That they may see, and know, and consider, and understand together, that the hand of the Lord hath done this, and the Holy One of Israel hath created it.", "web": "that they may see, know, consider, and understand together, that the hand of Yahweh has done this, and the Holy One of Israel has created it.", "bsb": "so that all may see and know, may consider and understand, that the hand of the LORD has done this and the Holy One of Israel has created it.”", "asv": "that they may see, and know, and consider, and understand together, that the hand of Jehovah hath done this, and the Holy One of Israel hath created it.", "ylt": "So that they see, and know, And regard, and act wisely together, For the hand of Jehovah hath done this, And the Holy One of Israel hath prepared it.", "dra": "That they may see and know, and consider, and understand together that the hand of the Lord hath done this, and the Holy One of Israel hath created it.", "bbe": "So that they may see and be wise and give their mind to it, and that it may be clear to them all that the hand of the Lord has done this, and that the Holy One of Israel has made it.", "geneva": "Therefore let them see and knowe, and let them consider and vnderstande together that the hand of the Lord hath done this, and the holy one of Israel hath created it.", "wycliffe": "That thei se, and knowe, and bithenke, and vndurstonde togidere; that the hond of the Lord dide this thing, and the hooli of Israel made that of nouyt.", "rotherham": "That men may see and observe and consider and understand at once, That, the hand of Yahweh, hath done this, That the Holy One of Israel hath created it.", "darby": "that they may see, and know, and consider, and understand together, that the hand of Jehovah hath done this, and the Holy One of Israel hath created it.", "twenty": "", "jps": "That they may see, and know, and consider, and understand together, that the hand of HaShem hath done this, and the Holy One of Israel hath created it.", "acv": "that they may see, and know, and consider, and understand together, that the hand of Jehovah has done this, and the Holy One of Israel has created it.", "anderson": "", "haweis": "", "noyes": "That they may see, and know, And consider, and understand together, That the hand of Jehovah hath done this, And that the Holy One of Israel hath created it.", "webster": "That they may see, and know, and consider, and understand together, that the hand of the LORD hath done this, and the Holy One of Israel hath created it.", "vulgate": "ut videant et sciant et recogitent et intellegant pariter quia manus Domini fecit hoc et Sanctus Israhel creavit illud;", "brenton": "that they may see, and know, and perceive, and understand together, that the hand of the Lord has wrought these works, and the Holy One of Israel has displayed them."}}, {"v": 21, "ref": "41:21", "o": "קָרְב֥וּ רִֽיבְ/כֶ֖ם יֹאמַ֣ר יְהוָ֑ה הַגִּ֨ישׁוּ֙ עֲצֻמ֣וֹתֵי/כֶ֔ם יֹאמַ֖ר מֶ֥לֶךְ יַעֲקֹֽב", "en": {"kjv": "Produce your cause, saith the Lord; bring forth your strong reasons, saith the King of Jacob.", "web": "Produce your cause,” says Yahweh. “Bring out your strong reasons,” says the King of Jacob.", "bsb": "“Present your case,” says the LORD. “Submit your arguments,” says the King of Jacob.", "asv": "Produce your cause, saith Jehovah; bring forth your strong reasons, saith the King of Jacob.", "ylt": "Bring near your cause, saith Jehovah, Bring nigh your mighty ones, saith the king of Jacob.", "dra": "Bring your cause near, saith the Lord: bring hither, if you have any thing to allege, saith the King of Jacob.", "bbe": "Put forward your cause, says the Lord; let your strong argument come out, says the King of Jacob.", "geneva": "Stand to your cause, saith the Lord: bring forth your strong reasons, saith ye King of Iaakob.", "wycliffe": "Make ye niy youre doom, seith the Lord; brynge ye, if in hap ye han ony thing, seith the kyng of Jacob.", "rotherham": "Bring near your contention, Saith Yahweh,—Advance your defences, Saith the King of Jacob:", "darby": "Produce your cause, saith Jehovah; bring forward your arguments, saith the King of Jacob.", "twenty": "", "jps": "Produce your cause, saith HaShem; bring forth your reasons, saith the King of Jacob.", "acv": "Produce your case, says Jehovah. Bring forth your strong reasons, says the King of Jacob.", "anderson": "", "haweis": "", "noyes": "Bring forward your cause, saith Jehovah; Produce your strong reasons, saith the king of Jacob.", "webster": "Produce your cause, saith the LORD; bring forth your strong [reasons], saith the King of Jacob.", "vulgate": "prope facite iudicium vestrum dicit Dominus adferte si quid forte habetis dixit Rex Iacob;", "brenton": "Your judgment draws nigh, saith the Lord God; your counsels have drawn nigh, saith the King of Jacob."}}, {"v": 22, "ref": "41:22", "o": "יַגִּ֨ישׁוּ֙ וְ/יַגִּ֣ידוּ לָ֔/נוּ אֵ֖ת אֲשֶׁ֣ר תִּקְרֶ֑ינָה הָ/רִאשֹׁנ֣וֹת מָ֣ה הֵ֗נָּה הַגִּ֜ידוּ וְ/נָשִׂ֤ימָה לִבֵּ֨/נוּ֙ וְ/נֵדְעָ֣ה אַחֲרִיתָ֔/ן א֥וֹ הַ/בָּא֖וֹת הַשְׁמִיעֻֽ/נוּ", "en": {"kjv": "Let them bring them forth, and shew us what shall happen: let them shew the former things, what they be, that we may consider them, and know the latter end of them; or declare us things for to come.", "web": "“Let them announce, and declare to us what shall happen. Declare the former things, what they are, that we may consider them, and know the latter end of them; or show us things to come.", "bsb": "“Let them come and tell us what will happen. Tell the former things, so that we may reflect on them and know the outcome. Or announce to us what is coming.", "asv": "Let them bring forth, and declare unto us what shall happen: declare ye the former things, what they are, that we may consider them, and know the latter end of them; or show us things to come.", "ylt": "They bring nigh, and declare to us that which doth happen, The first things--what they are declare ye, And we set our heart, and know their latter end, Or the coming things cause us to hear.", "dra": "Let them come, and tell us all things that are to come: tell us the former things what they were: and we will set our heart upon them and shall know the latter end of them, and tell us the things that are to come.", "bbe": "Let the future be made clear to us: give us news of the past things, so that we may give thought to them; or of the things to come, so that we may see if they are true.", "geneva": "Let them bring foorth, and let them tell vs what shall come: let them shew the former things what they be, that wee may consider them, and knowe the latter ende of them: either declare vs things for to come.", "wycliffe": "Neiy tho, and telle to vs, what euer thingis schulen come; telle ye the formere thingis that weren, and we schulen sette oure herte, and schulen wite; schewe ye to vs the laste thingis of hem, and tho thingis that schulen come.", "rotherham": "Let them advance them, and tell us, What shall happen,—Things known in advance—what they were, tell ye, That we may lay them to our heart and mark the after-story of them, Or, things yet to come, let us hear:", "darby": "Let them bring them forward, and declare to us what shall happen: shew the former things, what they are, that we may give attention to them, and know the end of them; — or let us hear things to come:", "twenty": "", "jps": "Let them bring them forth, and declare unto us the things that shall happen; the former things, what are they? Declare ye, that we may consider, and know the end of them; or announce to us things to come.", "acv": "Let them bring forth, and declare to us what shall happen. Declare ye the former things, what they are, that we may consider them, and know the latter end of them, or show us things to come.", "anderson": "", "haweis": "", "noyes": "Let them produce them, and show us what shall happen! Tell us what ye have predicted in times past, That we may consider, and know its fulfilment! Or declare to us things that are to come!", "webster": "Let them bring [them] forth, and show us what shall happen: let them show the former things, what they [are] that we may consider them, and know the latter end of them; or declare to us things to come.", "vulgate": "accedant et nuntient nobis quaecumque ventura sunt priora quae fuerint nuntiate et ponemus cor nostrum et sciemus novissima eorum et quae ventura sunt indicate nobis;", "brenton": "Let them draw nigh, and declare to you what things shall come to pass; or tell us what things were of old, and we will apply our understanding, and we shall know what are the last and the future things:"}}, {"v": 23, "ref": "41:23", "o": "הַגִּ֨ידוּ֙ הָ/אֹתִיּ֣וֹת לְ/אָח֔וֹר וְ/נֵ֣דְעָ֔ה כִּ֥י אֱלֹהִ֖ים אַתֶּ֑ם אַף תֵּיטִ֣יבוּ וְ/תָרֵ֔עוּ וְ/נִשְׁתָּ֖עָה ו/נרא וְ/נִרְאֶ֥ה יַחְדָּֽו", "en": {"kjv": "Shew the things that are to come hereafter, that we may know that ye are gods: yea, do good, or do evil, that we may be dismayed, and behold it together.", "web": "Declare the things that are to come hereafter, that we may know that you are gods. Yes, do good, or do evil, that we may be dismayed, and see it together.", "bsb": "Tell us the things that are to come, so that we may know that you are gods. Yes, do something good or evil, that we may look on together in dismay.", "asv": "Declare the things that are to come hereafter, that we may know that ye are gods: yea, do good, or do evil, that we may be dismayed, and behold it together.", "ylt": "Declare the things that are coming hereafter, And we know that ye are gods, Yea, ye may do good or do evil, And we look around and see it together.", "dra": "Shew the things that are to come hereafter, and we shall know that ye are gods. Do ye also good or evil, if you can: and let us speak, and see together.", "bbe": "Give us word of what will be after this, so that we may be certain that you are gods: yes, do good or do evil, so that we may all see it and be surprised.", "geneva": "Shewe the things that are to come hereafter, that we may know that you are gods: yea, doe good or doe euill, that we may declare it, and beholde it together.", "wycliffe": "Telle ye what thingis schulen come in tyme to comynge, and we schulen wite, that ye ben goddis; al so do ye wel, ethir yuele, if ye moun; and speke we, and see we togidere.", "rotherham": "Tell ye the events which shall be here-after, That we may perceive that gods, ye are,—Surely ye must do something—good or bad, That we may be amazed and behold it, at once.", "darby": "declare the things that are to happen hereafter, that we may know that ye aregods; yea, do good, or do evil, that we may be astonished, and behold it together.", "twenty": "", "jps": "Declare the things that are to come hereafter, that we may know that ye are gods; yea, do good, or do evil, that we may be dismayed, and behold it together.", "acv": "Declare the things that are to come hereafter, that we may know that ye are gods. Yea, do good, or do evil, that we may be dismayed, and behold it together.", "anderson": "", "haweis": "", "noyes": "Let us hear what shall happen in future times, That we may know whether ye are gods; Do something, be it good or evil, That we may be astonished, and see it together!", "webster": "Show the things that are to come hereafter, that we may know that ye [are] gods: yes, do good, or do evil, that we may be dismayed, and behold [it] together.", "vulgate": "adnuntiate quae ventura sunt in futurum et sciemus quia dii estis vos bene quoque aut male si potestis facite et loquamur et videamus simul;", "brenton": "tell us, declare ye to us the things that are coming on at the last time, and we shall know that ye are gods: do good, and do evil, and we shall wonder, and see at the same time"}}, {"v": 24, "ref": "41:24", "o": "הֵן אַתֶּ֣ם מֵ/אַ֔יִן וּ/פָעָלְ/כֶ֖ם מֵ/אָ֑פַע תּוֹעֵבָ֖ה יִבְחַ֥ר בָּ/כֶֽם", "en": {"kjv": "Behold, ye are of nothing, and your work of nought: an abomination is he that chooseth you.", "web": "Behold, you are of nothing, and your work is of nothing. He who chooses you is an abomination.", "bsb": "Behold, you are nothing and your work is of no value. Anyone who chooses you is detestable.", "asv": "Behold, ye are of nothing, and your work is of nought; an abomination is he that chooseth you.", "ylt": "Lo, ye are of nothing, and your work of nought, An abomination--it fixeth on you.", "dra": "Behold, you are of nothing, and your work of that which hath no being: he that hath chosen you is an abomination.", "bbe": "But you are nothing, and your work is of no value: foolish is he who takes you for his gods.", "geneva": "Beholde, ye are of no value, and your making is of naught: man hath chosen an abomination by them.", "wycliffe": "Lo! ye ben of nouyt, and youre werk is of that that is not; he that chees you, is abhomynacioun.", "rotherham": "Lo! ye, are, of nought, And your work is a puff of breath,—An abomination, he that chooseth you!", "darby": "Behold, ye are less than nothing, and your work is of nought; an abomination is he that chooseth you. ...", "twenty": "", "jps": "Behold, ye are nothing, and your work a thing of nought; an abomination is he that chooseth you.", "acv": "Behold, ye are of nothing, and your work is of naught. An abomination is he who chooses you.", "anderson": "", "haweis": "", "noyes": "Behold, ye are less than nothing, And your work is less than naught; An abomination is he that chooseth you!", "webster": "Behold, ye [are] of nothing, and your work of naught: an abomination [is he that] chooseth you.", "vulgate": "ecce vos estis ex nihilo et opus vestrum ex eo quod non est abominatio est qui elegit vos;", "brenton": "whence ye are, and whence is your works: they have chosen you an abomination out of the earth."}}, {"v": 25, "ref": "41:25", "o": "הַעִיר֤וֹתִי מִ/צָּפוֹן֙ וַ/יַּ֔את מִ/מִּזְרַח שֶׁ֖מֶשׁ יִקְרָ֣א בִ/שְׁמִ֑/י וְ/יָבֹ֤א סְגָנִים֙ כְּמוֹ חֹ֔מֶר וּ/כְמ֥וֹ יוֹצֵ֖ר יִרְמָס טִֽיט", "en": {"kjv": "I have raised up one from the north, and he shall come: from the rising of the sun shall he call upon my name: and he shall come upon princes as upon morter, and as the potter treadeth clay.", "web": "“I have raised up one from the north, and he has come; from the rising of the sun, one who calls on my name; and he shall come on rulers as on mortar, and as the potter treads clay.", "bsb": "I have raised up one from the north, and he has come— one from the east who calls on My name. He will march over rulers as if they were mortar, like a potter who treads the clay.", "asv": "I have raised up one from the north, and he is come; from the rising of the sun one that calleth upon my name: and he shall come upon rulers as upon mortar, and as the potter treadeth clay.", "ylt": "I have stirred up one from the north, And he cometh, From the rising of the sun he calleth in My name, And he cometh in on prefects as on clay, And as a potter treadeth down mire.", "dra": "I have raised up one from the north, and he shall come from the rising of the sun: he shall call upon my name, and he shall make princes to be as dirt, and as the potter treading clay.", "bbe": "I have sent for one from the north, and from the dawn he has come; in my name he will get rulers together and go against them; they will be like dust, even as the wet earth is stamped on by the feet of the potter.", "geneva": "I haue raised vp from the North, and he shall come: from the East sunne shall he cal vpon my Name, and shall come vpon princes as vpon clay, and as the potter treadeth myre vnder the foote.", "wycliffe": "I reiside fro the north, and he schal come fro the risyng of the sunne; he schal clepe my name. And he schal brynge magistratis as cley, and as a pottere defoulynge erthe.", "rotherham": "I have roused up one from the North, and he hath come, From the rising of the sun, calleth he on my Name,—And he hath come, on deputies, as though they were mortar, And as a potter treadeth clay.", "darby": "I have raised up one from the north, and he shall come, — from the rising of the sun, he who will call upon my name; and he shall come upon princes as on mortar, and as the potter treadeth clay.", "twenty": "", "jps": "I have roused up one from the north, and he is come, from the rising of the sun one that calleth upon My name; and he shall come upon rulers as upon mortar, and as the potter treadeth clay.", "acv": "I have raised up him from the north, and he has come, him who calls upon my name from the rising of the sun. And he shall come upon rulers as upon mortar, and as the potter treads clay.", "anderson": "", "haweis": "", "noyes": "I have raised up one from the north, and he cometh; From the rising of the sun he calleth upon my name; He trampleth upon princes as upon mortar; As the potter treadeth down the clay.", "webster": "I have raised up [one] from the north, and he shall come: from the rising of the sun shall he call upon my name: and he shall come upon princes as [upon] mortar, and as the potter treadeth clay.", "vulgate": "suscitavi ab aquilone et venit ab ortu solis vocabit nomen meum et adducet magistratus quasi lutum et velut plastes conculcans humum;", "brenton": "But I have raised up him that comes from the north, and him that comes from the rising of the sun: they shall be called by my name: let the princes come, and as potter's clay, and as a potter treading clay, so shall ye be trodden down."}}, {"v": 26, "ref": "41:26", "o": "מִֽי הִגִּ֤יד מֵ/רֹאשׁ֙ וְ/נֵדָ֔עָה וּ/מִ/לְּ/פָנִ֖ים וְ/נֹאמַ֣ר צַדִּ֑יק אַ֣ף אֵין מַגִּ֗יד אַ֚ף אֵ֣ין מַשְׁמִ֔יעַ אַ֥ף אֵין שֹׁמֵ֖עַ אִמְרֵי/כֶֽם", "en": {"kjv": "Who hath declared from the beginning, that we may know? and beforetime, that we may say, He is righteous? yea, there is none that sheweth, yea, there is none that declareth, yea, there is none that heareth your words.", "web": "Who has declared it from the beginning, that we may know? And before, that we may say, ‘He is right?’ Surely, there is no one who declares. Surely, there is no one who shows. Surely, there is no one who hears your words.", "bsb": "Who has declared this from the beginning, so that we may know, and from times past, so that we may say: ‘He was right’? No one announced it, no one foretold it, no one heard your words.", "asv": "Who hath declared it from the beginning, that we may know? and beforetime, that we may say, He is right? yea, there is none that declareth, yea, there is none that showeth, yea, there is none that heareth your words.", "ylt": "Who hath declared from the first, and we know? And beforetime, and we say, `Righteous?' yea, there is none declaring, Yea, there is none proclaiming, Yea, there is none hearing your sayings.", "dra": "Who hath declared from the beginning, that we may know: and from time of old, that we may say: Thou art just. There is none that sheweth, nor that foretelleth, nor that heareth your words.", "bbe": "Who has given knowledge of it from the first, so that we may be certain of it? and from the start, so that we may say, His word is true? There is no one who gives news, or says anything, or who gives ear to your words.", "geneva": "Who hath declared from the beginning, that we may knowe? or before time, that we may say, He is righteous? Surely there is none that sheweth: surely there is none that declareth: surely there is none that heareth your wordes.", "wycliffe": "Who tolde fro the bigynnyng, that we wite, and fro the bigynnyng, that we seie, Thou art iust? noon is tellynge, nether biforseiynge, nether herynge youre wordis.", "rotherham": "Who hath told in advance, that we might know, And beforetime, that we might say Right! Nay, there is none who can tell. Nay, there is none who can let us hear, Nay, there is none who can understand what ye utter.", "darby": "Who hath declared [it] from the beginning, that we may know? and beforetime, that we may say, [It is] right? Indeed, there is none that declareth; no, none that sheweth; no, none that heareth your words.", "twenty": "", "jps": "Who hath declared from the beginning, that we may know? and beforetime, that we may say that he is right? Yea, there is none that declareth, yea, there is none that announceth, yea, there is none that heareth your utterances.", "acv": "Who has declared it from the beginning, that we may know, and beforetime, that we may say, He is right? Yea, there is none who declares. Yea, there is none who shows. Yea, there is none who hears your words.", "anderson": "", "haweis": "", "noyes": "Who hath declared this from the beginning, that we might know it, And long ago, that we might say, It is true? There was not one that foretold it, not one that declared it, Not one that heard your words.", "webster": "Who hath declared from the beginning, that we may know? and before time, that we may say, [He is] righteous? verily, [there is] none that showeth, verily, [there is] none that declareth, verily, [there is] none that heareth your words.", "vulgate": "quis adnuntiavit ab exordio ut sciamus et a principio ut dicamus iustus es non est neque adnuntians neque praedicens neque audiens sermones vestros;", "brenton": "For who will declare the things from the beginning, that we may know also the former things, and we will say that they are true? there is no one that speaks beforehand, nor anyone that hears your words."}}, {"v": 27, "ref": "41:27", "o": "רִאשׁ֥וֹן לְ/צִיּ֖וֹן הִנֵּ֣ה הִנָּ֑/ם וְ/לִ/ירוּשָׁלִַ֖ם מְבַשֵּׂ֥ר אֶתֵּֽן", "en": {"kjv": "The first shall say to Zion, Behold, behold them: and I will give to Jerusalem one that bringeth good tidings.", "web": "I am the first to say to Zion, ‘Behold, look at them;’ and I will give one who brings good news to Jerusalem.", "bsb": "I was the first to tell Zion: ‘Look, here they are!’ And I gave to Jerusalem a herald of good news.", "asv": "I am the first that saith unto Zion, Behold, behold them; and I will give to Jerusalem one that bringeth good tidings.", "ylt": "First to Zion, Behold, behold them, And to Jerusalem one proclaiming tidings I give,", "dra": "The first shall say to Sion: Behold they are here, and to Jerusalem I will give an evangelist.", "bbe": "I was the first to give word of it to Zion, and I gave the good news to Jerusalem.", "geneva": "I am the first, that saieth to Zion, Beholde, beholde them: and I will giue to Ierusalem one that shall bring good tidings.", "wycliffe": "The firste schal seie to Sion, Lo! Y am present; and Y schal yyue a gospellere to Jerusalem.", "rotherham": "He who is First, [can say], To Zion, Lo! there they are! And to Jerusalem, A herald of good-tidings, do I give.", "darby": "The first, [I said] to Zion, Behold, behold them! and to Jerusalem, I will give one that bringeth glad tidings.", "twenty": "", "jps": "A harbinger unto Zion will I give: 'Behold, behold them', and to Jerusalem a messenger of good tidings.", "acv": "First to Zion. Behold, behold them, and I will give to Jerusalem him who brings good news.", "anderson": "", "haweis": "", "noyes": "I first said to Zion, Behold! behold them! And I gave to Jerusalem a messenger of glad tidings.", "webster": "The first [shall say] to Zion, Behold, behold them: and I will give to Jerusalem one that bringeth good tidings.", "vulgate": "primus ad Sion dicet ecce adsunt et Hierusalem evangelistam dabo;", "brenton": "I will give dominion to Sion, and will comfort Jerusalem by the way."}}, {"v": 28, "ref": "41:28", "o": "וְ/אֵ֨רֶא֙ וְ/אֵ֣ין אִ֔ישׁ וּ/מֵ/אֵ֖לֶּה וְ/אֵ֣ין יוֹעֵ֑ץ וְ/אֶשְׁאָלֵ֖/ם וְ/יָשִׁ֥יבוּ דָבָֽר", "en": {"kjv": "For I beheld, and there was no man; even among them, and there was no counsellor, that, when I asked of them, could answer a word.", "web": "When I look, there is no man; even among them there is no counselor who, when I ask of them, can answer a word.", "bsb": "When I look, there is no one; there is no counselor among them; when I ask them, they have nothing to say.", "asv": "And when I look, there is no man: even among them there is no counsellor, that, when I ask of them, can answer a word.", "ylt": "And I see that there is no man, Yea, of these that there is no counsellor, And I ask them, and they return word:", "dra": "And I saw, and there was no one even among them to consult, or who, when I asked, could answer a word.", "bbe": "And I saw that there was no man, even no wise man among them, who might give an answer to my questions.", "geneva": "But when I behelde, there was none, and when I inquired of them, there was no counsellor, and when I demaunded of them, they answered not a woorde.", "wycliffe": "And Y siy, and noon was of these, that token councel, and he that was axid, answeride a word.", "rotherham": "So I look, And there is not, a Man! Even among these And there is none to advise,—That, when I ask them, can answer a word.", "darby": "And I beheld, and there was no man; even among them, — and there was no counsellor, that, when I asked of them, could answer a word.", "twenty": "", "jps": "And I look, but there is no man; even among them, but there is no counsellor, that, when I ask of them, can give an answer.", "acv": "And when I look, there is no man. Even among them there is no counselor, that, when I ask of them, can answer a word.", "anderson": "", "haweis": "", "noyes": "I looked, but there was no man; Even among them, but there was none that gave counsel; I inquired of them that they might give an answer;", "webster": "For I beheld, and [there was] no man; even among them, and [there was] no counselor, that, when I asked of them, could answer a word.", "vulgate": "et vidi et non erat neque ex istis quisquam qui iniret consilium et interrogatus responderet verbum;", "brenton": "For from among the nations, behold, there was no one; and of their idols there was none to declare anything: and if I should ask them, Whence are ye? they could not answer me."}}, {"v": 29, "ref": "41:29", "o": "הֵ֣ן כֻּלָּ֔/ם אָ֥וֶן אֶ֖פֶס מַעֲשֵׂי/הֶ֑ם ר֥וּחַ וָ/תֹ֖הוּ נִסְכֵּי/הֶֽם", "en": {"kjv": "Behold, they are all vanity; their works are nothing: their molten images are wind and confusion.", "web": "Behold, all of them, their works are vanity and nothing. Their molten images are wind and confusion.", "bsb": "See, they are all a delusion; their works amount to nothing; their images are as empty as the wind.", "asv": "Behold, all of them, their works are vanity and nought; their molten images are wind and confusion.", "ylt": "`Lo, all of them are vanity, Nought are their works, Wind and emptiness their molten images!'", "dra": "Behold they are all in the wrong, and their works are vain: their idols are wind and vanity.", "bbe": "Truly they are all nothing, their works are nothing and of no value: their metal images are of no more use than wind.", "geneva": "Beholde, they are all vanitie: their worke is of nothing, their images are wind and confusion.", "wycliffe": "Lo! alle men ben vniust, and her werkis ben wynd and veyn; the symylacris of hem ben wynd, and voide thing.", "rotherham": "Lo! as to all of them, Vanity—nothingness, are their works, Wind and emptiness, their molten images!", "darby": "Behold, they are all vanity, their works are nought, their molten images are wind and emptiness.", "twenty": "", "jps": "Behold, all of them, their works are vanity and nought; their molten images are wind and confusion.", "acv": "Behold, all of them, their works are vanity and nothing. Their molten images are wind and confusion.", "anderson": "", "haweis": "", "noyes": "But behold, they are all vanity; Their works are nothing; Wind and emptiness are their molten images.", "webster": "Behold, they [are] all vanity, their works [are] nothing: their molten images [are] wind and confusion.", "vulgate": "ecce omnes iniusti et vana opera eorum ventus et inane simulacra eorum;", "brenton": "For these are your makers, as ye think, and they that cause you to err in vain."}}]}, {"c": 42, "verses": [{"v": 1, "ref": "42:1", "o": "הֵ֤ן עַבְדִּ/י֙ אֶתְמָךְ בּ֔/וֹ בְּחִירִ֖/י רָצְתָ֣ה נַפְשִׁ֑/י נָתַ֤תִּי רוּחִ/י֙ עָלָ֔י/ו מִשְׁפָּ֖ט לַ/גּוֹיִ֥ם יוֹצִֽיא", "en": {"kjv": "Behold my servant, whom I uphold; mine elect, in whom my soul delighteth; I have put my spirit upon him: he shall bring forth judgment to the Gentiles.", "web": "“Behold, my servant, whom I uphold; my chosen, in whom my soul delights— I have put my Spirit on him. He will bring justice to the nations.", "bsb": "“Here is My Servant, whom I uphold, My Chosen One, in whom My soul delights. I will put My Spirit on Him, and He will bring justice to the nations.", "asv": "Behold, my servant, whom I uphold; my chosen, in whom my soul delighteth: I have put my Spirit upon him; he will bring forth justice to the Gentiles.", "ylt": "Lo, My servant, I take hold on him, My chosen one--My soul hath accepted, I have put My Spirit upon him, Judgment to nations he bringeth forth.", "dra": "Behold my servant, I will uphold him: my elect, my soul delighteth in him: I have given my spirit upon him, he shall bring forth judgment to the Gentiles.", "bbe": "See my servant, whom I am supporting, my loved one, in whom I take delight: I have put my spirit on him; he will give the knowledge of the true God to the nations.", "geneva": "Behold, my seruaunt: I will stay vpon him: mine elect, in whom my soule deliteth: I haue put my Spirit vpon him: he shall bring forth iudgement to the Gentiles.", "wycliffe": "Lo! my seruaunt, Y schal vptake hym, my chosun, my soule pleside to it silf in hym. I yaf my spirit on hym, he schal brynge forth doom to hethene men.", "rotherham": "Lo! my Servant, I will uphold him, My chosen, well-pleased is my soul,—I have put my spirit upon him, Justice—to the nations, will he bring forth:", "darby": "Behold my servant whom I uphold, mine elect [in whom] my soul delighteth! I will put my Spirit upon him; he shall bring forth judgment to the nations.", "twenty": "", "jps": "Behold My servant, whom I uphold; Mine elect, in whom My soul delighteth; I have put My spirit upon him, he shall make the right to go forth to the nations.", "acv": "Behold, my servant, whom I uphold, my chosen, in whom my soul delights. I have put my Spirit upon him, he will bring forth justice to the Gentiles.", "anderson": "", "haweis": "", "noyes": "Behold my servant, whom I uphold, My chosen, in whom my soul delighteth, I have put my spirit upon him; He shall cause law to go forth to the nations.", "webster": "Behold my servant, whom I uphold; my elect, [in whom] my soul delighteth; I have put my spirit upon him: he shall bring forth judgment to the Gentiles.", "vulgate": "ecce servus meus suscipiam eum electus meus conplacuit sibi in illo anima mea dedi spiritum meum super eum iudicium gentibus proferet;", "brenton": "Jacob is my servant, I will help him: Israel is my chosen, my soul has accepted him; I have put my Spirit upon him; he shall bring forth judgment to the Gentiles."}}, {"v": 2, "ref": "42:2", "o": "לֹ֥א יִצְעַ֖ק וְ/לֹ֣א יִשָּׂ֑א וְ/לֹֽא יַשְׁמִ֥יעַ בַּ/ח֖וּץ קוֹלֽ/וֹ", "en": {"kjv": "He shall not cry, nor lift up, nor cause his voice to be heard in the street.", "web": "He will not shout, nor raise his voice, nor cause it to be heard in the street.", "bsb": "He will not cry out or raise His voice, nor make His voice heard in the streets.", "asv": "He will not cry, nor lift up his voice, nor cause it to be heard in the street.", "ylt": "He doth not cry, nor lift up, Nor cause his voice to be heard, in the street.", "dra": "He shall not cry, nor have respect to person, neither shall his voice be heard abroad.", "bbe": "He will make no cry, his voice will not be loud: his words will not come to men's ears in the streets.", "geneva": "He shall not crie, nor lift vp, nor cause his voice to be heard in the streete.", "wycliffe": "He schal not crie, nether he schal take a persoone, nether his vois schal be herd withoutforth.", "rotherham": "He will not cry out nor will he speak loud,—Nor cause to be heard, in the street, his voice:", "darby": "He shall not cry, nor lift up, nor cause his voice to be heard in the street.", "twenty": "", "jps": "He shall not cry, nor lift up, nor cause his voice to be heard in the street.", "acv": "He will not cry, nor lift up his voice, nor cause it to be heard in the street.", "anderson": "", "haweis": "", "noyes": "He shall not cry aloud, nor lift up his voice, Nor cause it to be heard in the street.", "webster": "He shall not cry, nor lift up, nor cause his voice to be heard in the street.", "vulgate": "non clamabit neque accipiet personam nec audietur foris vox eius;", "brenton": "He shall not cry, nor lift up his voice, nor shall his voice be heard without."}}, {"v": 3, "ref": "42:3", "o": "קָנֶ֤ה רָצוּץ֙ לֹ֣א יִשְׁבּ֔וֹר וּ/פִשְׁתָּ֥ה כֵהָ֖ה לֹ֣א יְכַבֶּ֑/נָּה לֶ/אֱמֶ֖ת יוֹצִ֥יא מִשְׁפָּֽט", "en": {"kjv": "A bruised reed shall he not break, and the smoking flax shall he not quench: he shall bring forth judgment unto truth.", "web": "He won’t break a bruised reed. He won’t quench a dimly burning wick. He will faithfully bring justice.", "bsb": "A bruised reed He will not break and a smoldering wick He will not extinguish; He will faithfully bring forth justice.", "asv": "A bruised reed will he not break, and a dimly burning wick will he not quench: he will bring forth justice in truth.", "ylt": "A bruised reed he breaketh not, And dim flax he quencheth not, To truth he bringeth forth judgment.", "dra": "The bruised reed he shall not break, and smoking flax he shall not quench, he shall bring forth judgment unto truth.", "bbe": "He will not let a crushed stem be quite broken, and he will not let a feebly burning light be put out: he will go on sending out the true word to the peoples.", "geneva": "A bruised reede shall hee not breake, and the smoking flaxe shall he not quench: he shall bring foorth iudgement in trueth.", "wycliffe": "He schal not breke a schakun rehed, and he schal not quenche smokynge flax; he schal brynge out doom in treuthe.", "rotherham": "Cane that is crushed, will he not break, And wick that is fading, will he not quench,—Faithfully, will he bring forth justice:", "darby": "A bruised reed shall he not break, and smoking flax shall he not quench: he shall bring forth judgment according to truth.", "twenty": "", "jps": "A bruised reed shall he not break, and the dimly burning wick shall he not quench; he shall make the right to go forth according to the truth.", "acv": "A bruised reed he will not break, and a dimly burning wick he will not quench, but he will bring forth justice in truth.", "anderson": "", "haweis": "", "noyes": "The bruised reed shall he not break, And the glimmering flax shall he not quench; He shall send forth law according to truth.", "webster": "A bruised reed shall he not break, and the smoking flax shall he not quench: he shall bring forth judgment to truth.", "vulgate": "calamum quassatum non conteret et linum fumigans non extinguet in veritate educet iudicium;", "brenton": "A bruised reed shall he not break, and smoking flax shall he not quench; but he shall bring forth judgment to truth."}}, {"v": 4, "ref": "42:4", "o": "לֹ֤א יִכְהֶה֙ וְ/לֹ֣א יָר֔וּץ עַד יָשִׂ֥ים בָּ/אָ֖רֶץ מִשְׁפָּ֑ט וּ/לְ/תוֹרָת֖/וֹ אִיִּ֥ים יְיַחֵֽילוּ", "en": {"kjv": "He shall not fail nor be discouraged, till he have set judgment in the earth: and the isles shall wait for his law.", "web": "He will not fail nor be discouraged, until he has set justice in the earth, and the islands will wait for his law.”", "bsb": "He will not grow weak or discouraged before He has established justice on the earth. In His law the islands will put their hope.”", "asv": "He will not fail nor be discouraged, till he have set justice in the earth; and the isles shall wait for his law.", "ylt": "He doth not become weak nor bruised, Till he setteth judgment in the earth, And for his law isles wait with hope.", "dra": "He shall not be sad, nor troublesome, till he set judgment in the earth, and the islands shall wait for his law.", "bbe": "His light will not be put out, and he will not be crushed, till he has given the knowledge of the true God to the earth, and the sea-lands will be waiting for his teaching.", "geneva": "He shall not faile nor be discouraged till he haue set iudgement in the earth: and the yles shall waite for his lawe.", "wycliffe": "He schal not be sorewful, nether troblid, til he sette doom in erthe, and ilis schulen abide his lawe.", "rotherham": "He will not fade, nor will he be crushed, Until he establish, in the earth, justice, And for his instruction, Coastlands, wait.", "darby": "He shall not faint nor be in haste, till he have set justice in the earth: and the isles shall wait for his law.", "twenty": "", "jps": "He shall not fail nor be crushed, till he have set the right in the earth; and the isles shall wait for his teaching.", "acv": "He will not fail nor be discouraged till he has set justice in the earth. And in his name Gentiles will hope.", "anderson": "", "haweis": "", "noyes": "He shall not fail, nor become weary, Until he shall have established justice in the earth. And distant nations shall wait for his law.", "webster": "He shall not fail nor be discouraged, till he hath set judgment in the earth: and the isles shall wait for his law.", "vulgate": "non erit tristis neque turbulentus donec ponat in terra iudicium et legem eius insulae expectabunt;", "brenton": "He shall shine out, and shall not be discouraged, until he have set judgment on the earth: and in his name shall the Gentiles trust."}}, {"v": 5, "ref": "42:5", "o": "כֹּֽה אָמַ֞ר הָ/אֵ֣ל יְהוָ֗ה בּוֹרֵ֤א הַ/שָּׁמַ֨יִם֙ וְ/נ֣וֹטֵי/הֶ֔ם רֹקַ֥ע הָ/אָ֖רֶץ וְ/צֶאֱצָאֶ֑י/הָ נֹתֵ֤ן נְשָׁמָה֙ לָ/עָ֣ם עָלֶ֔י/הָ וְ/ר֖וּחַ לַ/הֹלְכִ֥ים בָּֽ/הּ", "en": {"kjv": "Thus saith God the Lord, he that created the heavens, and stretched them out; he that spread forth the earth, and that which cometh out of it; he that giveth breath unto the people upon it, and spirit to them that walk therein:", "web": "Thus says God Yahweh, he who created the heavens and stretched them out, he who spread out the earth and that which comes out of it, he who gives breath to its people and spirit to those who walk in it.", "bsb": "This is what God the LORD says— He who created the heavens and stretched them out, who spread out the earth and its offspring, who gives breath to the people on it and life to those who walk in it:", "asv": "Thus saith God Jehovah, he that created the heavens, and stretched them forth; he that spread abroad the earth and that which cometh out of it; he that giveth breath unto the people upon it, and spirit to them that walk therein:", "ylt": "Thus said God, Jehovah, preparing The heavens, and stretching them out, Spreading out the earth and its productions, Giving breath to the people on it, And spirit to those walking in it.", "dra": "Thus saith the Lord God that created the heavens, and stretched them out: that established the earth, and the things that spring out of it: that giveth breath to the people upon it, and spirit to them that tread thereon.", "bbe": "God the Lord, even he who made the heavens, measuring them out on high; stretching out the earth, and giving its produce; he who gives breath to the people on it, and life to those who go about on it, says:", "geneva": "Thus sayeth God the Lord (he that created the heauens and spred them abroad: he that stretched foorth the earth, and the buddes thereof: he that giueth breath vnto the people vpon it, and spirit to them that walke therein)", "wycliffe": "The Lord God seith these thingis, makynge heuenes of noyt, and stretchynge forth tho, makynge stidfast the erthe, and tho thingis that buriownen of it, yyuynge breeth to the puple, that is on it, and yyuynge spirit to hem that treden on it.", "rotherham": "Thus, saith GOD himself—Yahweh,—Creator of the heavens that stretched them forth, Out-spreader of earth, and the products thereof,—Giver of breath to the people thereon, And of spirit to them who walk therein,", "darby": "Thus saithGod, Jehovah, he that created the heavens and stretched them out, he that spread forth the earth and its productions, he that giveth breath unto the people upon it, and spirit to them that walk therein:", "twenty": "", "jps": "Thus saith G-d HaShem, He that created the heavens, and stretched them forth, He that spread forth the earth and that which cometh out of it, He that giveth breath unto the people upon it, and spirit to them that walk therein:", "acv": "Thus says God, Jehovah, he who created the heavens, and stretched them forth, he who spread abroad the earth and that which comes out of it, he who gives breath to the people upon it, and spirit to those who walk in it,", "anderson": "", "haweis": "", "noyes": "Thus saith God Jehovah, Who created the heavens and stretched them out, Who spread forth the earth, and that which springeth forth from it, Who gave breath to the people upon it, And spirit to them that walk thereon:", "webster": "Thus saith God the LORD, he that created the heavens, and expanded them; he that spread forth the earth, and that which it produceth; he that giveth breath to the people upon it, and spirit to them that walk therein.", "vulgate": "haec dicit Dominus Deus creans caelos et extendens eos firmans terram et quae germinant ex ea dans flatum populo qui est super eam et spiritum calcantibus eam;", "brenton": "Thus saith the Lord God, who made the heaven, and established it; who settled the earth, and the things in it, and gives breath to the people on it, and spirit to them that tread on it:"}}, {"v": 6, "ref": "42:6", "o": "אֲנִ֧י יְהוָ֛ה קְרָאתִ֥י/ךָֽ בְ/צֶ֖דֶק וְ/אַחְזֵ֣ק בְּ/יָדֶ֑/ךָ וְ/אֶצָּרְ/ךָ֗ וְ/אֶתֶּנְ/ךָ֛ לִ/בְרִ֥ית עָ֖ם לְ/א֥וֹר גּוֹיִֽם", "en": {"kjv": "I the Lord have called thee in righteousness, and will hold thine hand, and will keep thee, and give thee for a covenant of the people, for a light of the Gentiles;", "web": "“I, Yahweh, have called you in righteousness, and will hold your hand, and will keep you, and make you a covenant for the people, as a light for the nations;", "bsb": "“I, the LORD, have called you for a righteous purpose, and I will take hold of your hand. I will keep you and appoint you to be a covenant for the people and a light to the nations,", "asv": "I, Jehovah, have called thee in righteousness, and will hold thy hand, and will keep thee, and give thee for a covenant of the people, for a light of the Gentiles;", "ylt": "I, Jehovah, did call thee in righteousness, And I lay hold on thy hand, and keep thee, And I give thee for a covenant of a people, And a light of nations.", "dra": "I the Lord have called thee in justice, and taken thee by the hand, and preserved thee. And I have given thee for a covenant of the people, for a light of the Gentiles:", "bbe": "I the Lord have made you the vessel of my purpose, I have taken you by the hand, and kept you safe, and I have given you to be an agreement to the people, and a light to the nations:", "geneva": "I the Lord haue called thee in righteousnesse, and will hold thine hand, and I will keepe thee, and giue thee for a couenant of the people, and for a light of the Gentiles,", "wycliffe": "Y the Lord haue clepid thee in riytfulnesse, and Y took thin hond, and kepte thee, and Y yaf thee in to a boond of pees of the puple, and in to liyt of folkis.", "rotherham": "I—Yahweh, have called thee in righteousness, And will firmly grasp thy hand,—And will keep thee And give thee—As the covenant of a people, As the light of nations:", "darby": "I, Jehovah, have called thee in righteousness, and will take hold of thy hand; and I will preserve thee, and give thee for a covenant of the people, for a light of the nations,", "twenty": "", "jps": "I HaShem have called thee in righteousness, and have taken hold of thy hand, and kept thee, and set thee for a covenant of the people, for a light of the nations;", "acv": "I, Jehovah, have called thee in righteousness, and will hold thy hand, and will keep thee, and give thee for a covenant of the people, for a light of the Gentiles,", "anderson": "", "haweis": "", "noyes": "I, Jehovah, have called thee for salvation; I will hold thee by the hand; I will defend thee, and make thee a covenant to the people, A light to the nations;", "webster": "I the LORD have called thee in righteousness, and will hold thy hand, and will keep thee, and give thee for a covenant of the people, for a light of the Gentiles;", "vulgate": "ego Dominus vocavi te in iustitia et adprehendi manum tuam et servavi et dedi te in foedus populi in lucem gentium;", "brenton": "I the Lord God have called thee in righteousness, and will hold thine hand, and will strengthen thee: and I have given thee for the covenant of a race, for a light of the Gentiles:"}}, {"v": 7, "ref": "42:7", "o": "לִ/פְקֹ֖חַ עֵינַ֣יִם עִוְר֑וֹת לְ/הוֹצִ֤יא מִ/מַּסְגֵּר֙ אַסִּ֔יר מִ/בֵּ֥ית כֶּ֖לֶא יֹ֥שְׁבֵי חֹֽשֶׁךְ", "en": {"kjv": "To open the blind eyes, to bring out the prisoners from the prison, and them that sit in darkness out of the prison house.", "web": "to open the blind eyes, to bring the prisoners out of the dungeon, and those who sit in darkness out of the prison.", "bsb": "to open the eyes of the blind, to bring prisoners out of the dungeon and those sitting in darkness out from the prison house.", "asv": "to open the blind eyes, to bring out the prisoners from the dungeon, and them that sit in darkness out of the prison-house.", "ylt": "To open the eyes of the blind, To bring forth from prison the bound one, From the house of restraint those sitting in darkness.", "dra": "That thou mightest open the eyes of the blind, and bring forth the prisoner out of prison, and them that sit in darkness out of the prison house.", "bbe": "To give eyes to the blind, to make free the prisoners from the prison, to let out those who are shut up in the dark.", "geneva": "That thou maist open the eyes of the blind, and bring out the prisoners from the prison: and them that sitte in darkenesse, out of the prison house.", "wycliffe": "That thou schuldist opene the iyen of blynde men; that thou schuldist lede out of closyng togidere a boundun man, fro the hous of prisoun men sittynge in derknessis.", "rotherham": "To open eyes that are blind,—To bring forth Out of the dungeon the captive Out of the prison, the dwellers in darkness.", "darby": "to open the blind eyes, to bring forth the prisoner from the prison, them that sit in darkness out of the house of restraint.", "twenty": "", "jps": "To open the blind eyes, to bring out the prisoners from the dungeon, and them that sit in darkness out of the prison-house.", "acv": "to open the blind eyes, to bring out the prisoners from the dungeon, and those who sit in darkness out of the prison-house.", "anderson": "", "haweis": "", "noyes": "To open the blind eyes, To bring out the prisoners from the prison, And them that sit in darkness out of the prison-house.", "webster": "To open the blind eyes, to bring out the prisoners from the prison, [and] them that sit in darkness out of the prison-house.", "vulgate": "ut aperires oculos caecorum et educeres de conclusione vinctum de domo carceris sedentes in tenebris;", "brenton": "to open the eyes of the blind, to bring the bound and them that sit in darkness out of bonds and the prison-house."}}, {"v": 8, "ref": "42:8", "o": "אֲנִ֥י יְהוָ֖ה ה֣וּא שְׁמִ֑/י וּ/כְבוֹדִ/י֙ לְ/אַחֵ֣ר לֹֽא אֶתֵּ֔ן וּ/תְהִלָּתִ֖/י לַ/פְּסִילִֽים", "en": {"kjv": "I am the Lord: that is my name: and my glory will I not give to another, neither my praise to graven images.", "web": "“I am Yahweh. That is my name. I will not give my glory to another, nor my praise to engraved images.", "bsb": "I am the LORD; that is My name! I will not yield My glory to another or My praise to idols.", "asv": "I am Jehovah, that is my name; and my glory will I not give to another, neither my praise unto graven images.", "ylt": "I am Jehovah, this is My name, And Mine honour to another I give not, Nor My praise to graven images.", "dra": "I the Lord, this is my name: I will not give my glory to another, nor my praise to graven things.", "bbe": "I am the Lord; that is my name: I will not give my glory to another, or my praise to pictured images.", "geneva": "I am the Lord, this is my Name, and my glory wil I not giue to another, neither my praise to grauen images.", "wycliffe": "Y am the Lord, this is my name; Y schal not yyue my glorie to an othere, and my preisyng to grauun ymagis.", "rotherham": "I, am Yahweh, that, is my Name, And, my glory, to another, will I not give, Nor my praise to images.", "darby": "I am Jehovah, that is my name; and my glory will I not give to another, neither my praise to graven images.", "twenty": "", "jps": "I am HaShem, that is My name; and My glory will I not give to another, neither My praise to graven images.", "acv": "I am Jehovah. That is my name, and I will not give my glory to another, nor my praise to graven images.", "anderson": "", "haweis": "", "noyes": "I am Jehovah, that is my name; And my glory will I not give to another, Nor my praise to graven images.", "webster": "I [am] the LORD: that [is] my name: and my glory will I not give to another, neither my praise to graven images.", "vulgate": "ego Dominus hoc est nomen meum gloriam meam alteri non dabo et laudem meam sculptilibus;", "brenton": "I am the Lord God: that is my name: I will not give my glory to another, nor my praises to graven images."}}, {"v": 9, "ref": "42:9", "o": "הָ/רִֽאשֹׁנ֖וֹת הִנֵּה בָ֑אוּ וַֽ/חֲדָשׁוֹת֙ אֲנִ֣י מַגִּ֔יד בְּ/טֶ֥רֶם תִּצְמַ֖חְנָה אַשְׁמִ֥יע אֶתְ/כֶֽם", "en": {"kjv": "Behold, the former things are come to pass, and new things do I declare: before they spring forth I tell you of them.", "web": "Behold, the former things have happened, and I declare new things. I tell you about them before they come up.”", "bsb": "Behold, the former things have happened, and now I declare new things. Before they spring forth I proclaim them to you.”", "asv": "Behold, the former things are come to pass, and new things do I declare; before they spring forth I tell you of them.", "ylt": "The former things, lo, have come, And new things I am declaring, Before they spring up I cause you to hear.", "dra": "The things that were first, behold they are come: and new things do I declare: before they spring forth, I will make you hear them.", "bbe": "See, the things said before have come about, and now I give word of new things: before they come I give you news of them.", "geneva": "Beholde, the former thinges are come to passe, and newe things doe I declare: before they come foorth, I tell you of them.", "wycliffe": "Lo! tho thingis that weren the firste, ben comun, and Y telle newe thingis; Y schal make herd to you, bifore that tho bigynnen to be maad.", "rotherham": "Things told in advance, lo! they have come to pass,—And new things, am I telling, Ere yet they spring forth, I let, you, hear them.", "darby": "Behold, the former things are come to pass, and new things do I declare: before they spring forth will I cause you to hear them.", "twenty": "", "jps": "Behold, the former things are come to pass, and new things do I declare; before they spring forth I tell you of them.", "acv": "Behold, the former things have come to pass, and I declare new things. Before they spring forth I tell you of them.", "anderson": "", "haweis": "", "noyes": "The former things, behold! they are come to pass, And new things do I now declare; Before they spring forth, I make them known to you.", "webster": "Behold, the former things have come to pass, and new things do I declare: before they spring forth I tell you of them.", "vulgate": "quae prima fuerant ecce venerunt nova quoque ego adnuntio antequam oriantur audita vobis faciam;", "brenton": "Behold, the ancient things have come to pass, and so will the new things which I tell you: yea, before I tell them they are made known to you."}}, {"v": 10, "ref": "42:10", "o": "שִׁ֤ירוּ לַֽ/יהוָה֙ שִׁ֣יר חָדָ֔שׁ תְּהִלָּת֖/וֹ מִ/קְצֵ֣ה הָ/אָ֑רֶץ יוֹרְדֵ֤י הַ/יָּם֙ וּ/מְלֹא֔/וֹ אִיִּ֖ים וְ/יֹשְׁבֵי/הֶֽם", "en": {"kjv": "Sing unto the Lord a new song, and his praise from the end of the earth, ye that go down to the sea, and all that is therein; the isles, and the inhabitants thereof.", "web": "Sing to Yahweh a new song, and his praise from the end of the earth, you who go down to the sea, and all that is therein, the islands and their inhabitants.", "bsb": "Sing to the LORD a new song— His praise from the ends of the earth— you who go down to the sea, and all that is in it, you islands, and all who dwell in them.", "asv": "Sing unto Jehovah a new song, and his praise from the end of the earth; ye that go down to the sea, and all that is therein, the isles, and the inhabitants thereof.", "ylt": "Sing to Jehovah a new song, His praise from the end of the earth, Ye who are going down to the sea, and its fulness, Isles, and their inhabitants.", "dra": "Sing ye to the Lord a new song, his praise is from the ends of the earth: you that go down to the sea, and all that are therein: ye islands, and ye inhabitants of them.", "bbe": "Make a new song to the Lord, and let his praise be sounded from the end of the earth; you who go down to the sea, and everything in it, the sea-lands and their people.", "geneva": "Sing vnto the Lord a newe song, and his praise from the ende of the earth: yee that goe downe to the sea, and all that is therein: the yles and the inhabitants thereof.", "wycliffe": "Synge ye a newe song to the Lord; his heriyng is fro the laste partis of erthe; ye that goon doun in to the see, and the fulnesse therof, ilis, and the dwelleris of tho.", "rotherham": "Sing to Yahweh, a song that is new, His praise, from the end of the earth,—Ye that go down to the sea, and the fulness thereof, The Coastlands and ye who dwell therein.", "darby": "Sing unto Jehovah a new song, his praise from the end of the earth, ye that go down to the sea, and all that is therein, the isles and their inhabitants.", "twenty": "", "jps": "Sing unto HaShem a new song, and His praise from the end of the earth; ye that go down to the sea, and all that is therein, the isles, and the inhabitants thereof.", "acv": "Sing to Jehovah a new song, and his praise from the end of the earth, ye who go down to the sea, and all that is therein, the isles, and the inhabitants thereof.", "anderson": "", "haweis": "", "noyes": "Sing to Jehovah a new song; His praise to the ends of the earth; Ye that go down upon the sea, and all that fill it; Ye distant coasts, and ye that dwell therein!", "webster": "Sing to the LORD a new song, [and] his praise from the end of the earth, ye that go down to the sea, and all that is in it; the isles, and their inhabitants.", "vulgate": "cantate Domino canticum novum laus eius ab extremis terrae qui descenditis in mare et plenitudo eius insulae et habitatores earum;", "brenton": "Sing a new hymn to the Lord: ye who are his dominion, glorify his name from the end of the earth: ye that go down to the sea, and sail upon it; the islands, and they that dwell in them."}}, {"v": 11, "ref": "42:11", "o": "יִשְׂא֤וּ מִדְבָּר֙ וְ/עָרָ֔י/ו חֲצֵרִ֖ים תֵּשֵׁ֣ב קֵדָ֑ר יָרֹ֨נּוּ֙ יֹ֣שְׁבֵי סֶ֔לַע מֵ/רֹ֥אשׁ הָרִ֖ים יִצְוָֽחוּ", "en": {"kjv": "Let the wilderness and the cities thereof lift up their voice, the villages that Kedar doth inhabit: let the inhabitants of the rock sing, let them shout from the top of the mountains.", "web": "Let the wilderness and its cities raise their voices, with the villages that Kedar inhabits. Let the inhabitants of Sela sing. Let them shout from the top of the mountains!", "bsb": "Let the desert and its cities raise their voices; let the villages of Kedar cry aloud. Let the people of Sela sing for joy; let them cry out from the mountaintops.", "asv": "Let the wilderness and the cities thereof lift up their voice, the villages that Kedar doth inhabit; let the inhabitants of Sela sing, let them shout from the top of the mountains.", "ylt": "The wilderness and its cities do lift up the voice , The villages Kedar doth inhabit, Sing do the inhabitants of Sela, From the top of mountains they cry.", "dra": "Let the desert and the cities thereof be exalted: Cedar shall dwell in houses: ye inhabitants of Petra, give praise, they shall cry from the top of the mountains.", "bbe": "Let the waste land and its flocks be glad, the tent-circles of Kedar; let the people of the rock give a glad cry, from the top of the mountains let them make a sound of joy.", "geneva": "Let the wildernesse and the cities thereof lift vp their voyce, the townes that Kedar doeth inhabite: let the inhabitants of the rocks sing: let them shoute from the toppe of the mountaines.", "wycliffe": "The desert be reisid, and the citees therof; he schal dwelle in the housis of Cedar; ye dwelleris of the stoon, herie ye; thei schulen crie fro the cop of hillis.", "rotherham": "Let the wilderness shout, and the cities thereof, The villages wherein dwelleth Kedar,—Let the inhabitants of the crag, raise shouts of triumph, From the top of the mountains, let them cry aloud:", "darby": "Let the wilderness and the cities thereof lift up [their voice], the villages that Kedar doth inhabit; let the inhabitants of the rock sing, let them shout from the top of the mountains:", "twenty": "", "jps": "Let the wilderness and the cities thereof lift up their voice, the villages that Kedar doth inhabit; let the inhabitants of Sela exult, let them shout from the top of the mountains.", "acv": "Let the wilderness and the cities of it lift up their voice, the villages that Kedar inhabits. Let the inhabitants of Sela sing. Let them shout from the top of the mountains.", "anderson": "", "haweis": "", "noyes": "Let the desert cry aloud, and the cities thereof; The villages, that Kedar inhabiteth; Let the inhabitants of the rock sing; Let them shout from the top of the mountains!", "webster": "Let the wilderness and its cities lift up [their voice], the villages [that] Kedar doth inhabit: let the inhabitants of the rock sing, let them shout from the top of the mountains.", "vulgate": "sublevetur desertum et civitates eius in domibus habitabit Cedar laudate habitatores Petrae de vertice montium clamabunt;", "brenton": "Rejoice, thou wilderness, and the villages thereof, the hamlets, and the dwellers in Kedar: the inhabitants of the rock shall rejoice, they shall shout from the top of the mountains."}}, {"v": 12, "ref": "42:12", "o": "יָשִׂ֥ימוּ לַֽ/יהוָ֖ה כָּב֑וֹד וּ/תְהִלָּת֖/וֹ בָּ/אִיִּ֥ים יַגִּֽידוּ", "en": {"kjv": "Let them give glory unto the Lord, and declare his praise in the islands.", "web": "Let them give glory to Yahweh, and declare his praise in the islands.", "bsb": "Let them give glory to the LORD and declare His praise in the islands.", "asv": "Let them give glory unto Jehovah, and declare his praise in the islands.", "ylt": "They ascribe to Jehovah honour, And His praise in the isles they declare.", "dra": "They shall give glory to the Lord, and shall declare his praise in the islands.", "bbe": "Let them give glory to the Lord, sounding his praise in the sea-lands.", "geneva": "Let them giue glorie vnto the Lord, and declare his praise in the ylands.", "wycliffe": "Thei schulen sette glorie to the Lord, and they schulen telle his heriyng in ilis.", "rotherham": "Let them render unto Yahweh, glory,—And, his praise, in the Coastlands let them tell.", "darby": "let them give glory unto Jehovah, and declare his praise in the islands.", "twenty": "", "jps": "Let them give glory unto HaShem, and declare His praise in the islands.", "acv": "Let them give glory to Jehovah, and declare his praise in the islands.", "anderson": "", "haweis": "", "noyes": "Let them give glory to Jehovah, And proclaim his praise in distant lands!", "webster": "Let them give glory to the LORD, and declare his praise in the isles.", "vulgate": "ponent Domino gloriam et laudem eius in insulis nuntiabunt;", "brenton": "They shall give glory to God, and shall proclaim his praises in the islands."}}, {"v": 13, "ref": "42:13", "o": "יְהוָה֙ כַּ/גִּבּ֣וֹר יֵצֵ֔א כְּ/אִ֥ישׁ מִלְחָמ֖וֹת יָעִ֣יר קִנְאָ֑ה יָרִ֨יעַ֙ אַף יַצְרִ֔יחַ עַל אֹיְבָ֖י/ו יִתְגַּבָּֽר", "en": {"kjv": "The Lord shall go forth as a mighty man, he shall stir up jealousy like a man of war: he shall cry, yea, roar; he shall prevail against his enemies.", "web": "Yahweh will go out like a mighty man. He will stir up zeal like a man of war. He will raise a war cry. Yes, he will shout aloud. He will triumph over his enemies.", "bsb": "The LORD goes forth like a mighty one; He stirs up His zeal like a warrior. He shouts; yes, He roars in triumph over His enemies:", "asv": "Jehovah will go forth as a mighty man; he will stir up his zeal like a man of war: he will cry, yea, he will shout aloud; he will do mightily against his enemies.", "ylt": "Jehovah as a mighty one goeth forth. As a man of war He stirreth up zeal, He crieth, yea, He shrieketh, Against His enemies He showeth Himself mighty.", "dra": "The Lord shall go forth as a mighty man, as a man of war shall he stir up zeal: he shall shout and cry: he shall prevail against his enemies.", "bbe": "The Lord will go out as a man of war, he will be moved to wrath like a fighting-man: his voice will be strong, he will give a loud cry; he will go against his attackers like a man of war.", "geneva": "The Lord shall go forth as a gyant: he shall stirre vp his courage like a man of warre: he shall shout and crie, and shall preuaile against his enemies.", "wycliffe": "The Lord as a strong man schal go out, as a man a werryour he schal reise feruent loue; he schal speke, and schal crie; he schal be coumfortid on hise enemyes.", "rotherham": "Yahweh, as a hero, goeth forth, As a man of war, he stirreth up jealousy,—He giveth a cry, yea he raiseth a war-cry, Over his foes, he showeth his strength.", "darby": "Jehovah will go forth as a mighty man, he will stir up jealousy like a man of war: he will cry, yea, he will shout; he will shew himself mighty against his enemies.", "twenty": "", "jps": "HaShem will go forth as a mighty man, He will stir up jealousy like a man of war; He will cry, yea, He will shout aloud, He will prove Himself mighty against His enemies.", "acv": "Jehovah will go forth as a mighty man. He will stir up his zeal like a man of war. He will cry, yea, he will shout aloud. He will do mightily against his enemies.", "anderson": "", "haweis": "", "noyes": "Jehovah shall march forth like a hero; Like a mighty warrior shall he rouse his indignation, He shall cry aloud; he shall shout the war-cry, And show himself mighty against his enemies.", "webster": "The LORD will go forth as a mighty man, he will stir up jealousy like a man of war: he will cry, yes, roar; he will prevail against his enemies.", "vulgate": "Dominus sicut fortis egredietur sicut vir proeliator suscitabit zelum vociferabitur et clamabit super inimicos suos confortabitur;", "brenton": "The Lord God of hosts shall go forth, and crush the war: he shall stir up jealousy, and shall shout mightily against his enemies."}}, {"v": 14, "ref": "42:14", "o": "הֶחֱשֵׁ֨יתִי֙ מֵֽ/עוֹלָ֔ם אַחֲרִ֖ישׁ אֶתְאַפָּ֑ק כַּ/יּוֹלֵדָ֣ה אֶפְעֶ֔ה אֶשֹּׁ֥ם וְ/אֶשְׁאַ֖ף יָֽחַד", "en": {"kjv": "I have long time holden my peace; I have been still, and refrained myself: now will I cry like a travailing woman; I will destroy and devour at once.", "web": "“I have been silent a long time. I have been quiet and restrained myself. Now I will cry out like a travailing woman. I will both gasp and pant.", "bsb": "“I have kept silent from ages past; I have remained quiet and restrained. But now I will groan like a woman in labor; I will at once gasp and pant.", "asv": "I have long time holden my peace; I have been still, and refrained myself: now will I cry out like a travailing woman; I will gasp and pant together.", "ylt": "I have kept silent from of old, I keep silent, I refrain myself, As a travailing woman I cry out, I desolate and swallow up together.", "dra": "I have always held my peace, I have kept silence, I have been patient, I will speak now as a woman in labour: I will destroy, and swallow up at once.", "bbe": "I have long been quiet, I have kept myself in and done nothing: now I will make sounds of pain like a woman in childbirth, breathing hard and quickly.", "geneva": "I haue a long time holden my peace: I haue beene still and refrained my selfe: nowe will I crie like a trauailing woman: I will destroy and deuoure at once.", "wycliffe": "Y was stille, euere Y helde silence; Y was pacient, Y schal speke as a womman trauelynge of child; Y schal scatere, and Y schal swolowe togidere.", "rotherham": "I have held my peace from age-past times, I kept still, I restrained myself,—As a travailing woman, I pant, I breathe hard and gasp, all at once!", "darby": "Long time have I holden my peace; I have been still, I have restrained myself: I will cry like a woman that travaileth; I will blow and pant at once.", "twenty": "", "jps": "I have long time held My peace, I have been still, and refrained Myself; now will I cry like a travailing woman, gasping and panting at once.", "acv": "I have for a long time held my peace. I have been still, and refrained myself. Now I will cry out like a travailing woman. I will gasp and pant together.", "anderson": "", "haweis": "", "noyes": "\"I have long held my peace; I have been still and refrained myself; But now will I cry like a woman in travail; I will destroy and swallow up at once.", "webster": "I have long time held my peace; I have been still, [and] restrained myself: [now] will I cry like a travailing woman; I will destroy and devour at once.", "vulgate": "tacui semper silui patiens fui sicut pariens loquar dissipabo et absorbebo simul;", "brenton": "I have been silent: shall I also always be silent and forbear: I have endured like a travailing woman: I will now amaze and wither at once."}}, {"v": 15, "ref": "42:15", "o": "אַחֲרִ֤יב הָרִים֙ וּ/גְבָע֔וֹת וְ/כָל עֶשְׂבָּ֖/ם אוֹבִ֑ישׁ וְ/שַׂמְתִּ֤י נְהָרוֹת֙ לָֽ/אִיִּ֔ים וַ/אֲגַמִּ֖ים אוֹבִֽישׁ", "en": {"kjv": "I will make waste mountains and hills, and dry up all their herbs; and I will make the rivers islands, and I will dry up the pools.", "web": "I will destroy mountains and hills, and dry up all their herbs. I will make the rivers islands, and will dry up the pools.", "bsb": "I will lay waste the mountains and hills and dry up all their vegetation. I will turn the rivers into dry land and drain the marshes.", "asv": "I will lay waste mountains and hills, and dry up all their herbs; and I will make the rivers islands, and will dry up the pools.", "ylt": "I make waste mountains and hills, And all their herbs I dry up, And I have made rivers become isles, And ponds I dry up.", "dra": "I will lay waste the mountains and hills, and will make all their grass to wither: and I will turn rivers into islands, and will dry up the standing pools.", "bbe": "I will make waste mountains and hills, drying up all their plants; and I will make rivers dry, and pools dry land.", "geneva": "I will make waste mountaines, and hilles, and drie vp all their herbes, and I will make the floods ylands, and I will drie vp the pooles.", "wycliffe": "Y schal make desert hiy mounteyns and litle hillis, and Y schal drie vp al the buriownyng of tho; and Y schal sette floodis in to ilis, and Y schal make poondis drie.", "rotherham": "I will lay waste mountains, and hills, And all their vegetation, will I wither,—And I will make rivers to be shores, And lakes, will I dry up:", "darby": "I will lay waste mountains and hills, and dry up all their herbs; and I will make the rivers islands, and I will dry up the pools.", "twenty": "", "jps": "I will make waste mountains and hills, and dry up all their herbs; and I will make the rivers islands, and will dry up the pools.", "acv": "I will lay waste mountains and hills, and dry up all their herbs. And I will make the rivers islands, and will dry up the pools.", "anderson": "", "haweis": "", "noyes": "I will lay waste mountains and hills, And dry up all their herbs. I will make the river solid land, And dry up the pools of water.", "webster": "I will make waste mountains and hills, and dry up all their herbs; and I will make the rivers [to be] islands, and I will dry up the pools.", "vulgate": "desertos faciam montes et colles et omne gramen eorum exsiccabo et ponam flumina in insulas et stagna arefaciam;", "brenton": "I will make desolate mountains and hills, and will dry up all their grass; and I will make the rivers islands, and dry up the pools."}}, {"v": 16, "ref": "42:16", "o": "וְ/הוֹלַכְתִּ֣י עִוְרִ֗ים בְּ/דֶ֨רֶךְ֙ לֹ֣א יָדָ֔עוּ בִּ/נְתִיב֥וֹת לֹֽא יָדְע֖וּ אַדְרִיכֵ֑/ם אָשִׂים֩ מַחְשָׁ֨ךְ לִ/פְנֵי/הֶ֜ם לָ/א֗וֹר וּ/מַֽעֲקַשִּׁים֙ לְ/מִישׁ֔וֹר אֵ֚לֶּה הַ/דְּבָרִ֔ים עֲשִׂיתִ֖/ם וְ/לֹ֥א עֲזַבְתִּֽי/ם", "en": {"kjv": "And I will bring the blind by a way that they knew not; I will lead them in paths that they have not known: I will make darkness light before them, and crooked things straight. These things will I do unto them, and not forsake them.", "web": "I will bring the blind by a way that they don’t know. I will lead them in paths that they don’t know. I will make darkness light before them, and crooked places straight. I will do these things, and I will not forsake them.", "bsb": "I will lead the blind by a way they did not know; I will guide them on unfamiliar paths. I will turn darkness into light before them and rough places into level ground. These things I will do for them, and I will not forsake them.", "asv": "And I will bring the blind by a way that they know not; in paths that they know not will I lead them; I will make darkness light before them, and crooked places straight. These things will I do, and I will not forsake them.", "ylt": "And I have caused the blind to go, In a way they have not known, In paths they have not known I cause them to tread, I make a dark place before them become light, And unlevelled places become a plain, These are the things I have done to them, And I have not forsaken them.", "dra": "And I will lead the blind into the way which they know not: and in the paths which they were ignorant of I will make them walk: I will make darkness light before them, and crooked things straight: these things have I done to them, and have not forsaken them.", "bbe": "And I will take the blind by a way of which they had no knowledge, guiding them by roads strange to them: I will make the dark places light before them, and the rough places level. These things will I do and will not give them up.", "geneva": "And I will bring the blinde by a way, that they knewe not, and lead them by paths that they haue not knowen: I will make darkenesse light before them, and crooked thinges straight. These thinges will I doe vnto them, and not forsake them.", "wycliffe": "And Y schal lede out blynde men in to the weie, which thei knowen not, and Y schal make hem to go in pathis, whiche thei knewen not; Y schal sette the derknessis of hem bifore hem in to liyt, and schrewid thingis in to riytful thingis; Y dide these wordis to hem, and Y forsook not hem.", "rotherham": "Thus will I lead the blind, by a way they know not, In paths they know not, will I guide them,—I will make the place that was dark before them to be, light. And crooked ways, to be, straight, These things, have I done unto them, And have not forsaken them.", "darby": "And I will bring the blind by a way that they know not, in paths that they know not will I lead them; I will make darkness light before them, and crooked things straight. These things will I do unto them, and not forsake them.", "twenty": "", "jps": "And I will bring the blind by a way that they knew not, in paths that they knew not will I lead them; I will make darkness light before them, and rugged places plain. These things will I do, and I will not leave them undone.", "acv": "And I will bring the blind by a way that they know not. I will lead them in paths that they know not. I will make darkness light before them, and crooked places straight. These things I will do, and I will not forsake them.", "anderson": "", "haweis": "", "noyes": "Then will I lead the blind in a way which they know not, And in unknown paths will I guide them; I will make darkness light before them, And crooked paths straight; These things will I do for them, and not forsake them.\"", "webster": "And I will bring the blind by a way [that] they knew not; I will lead them in paths [that] they have not known: I will make darkness light before them, and crooked things straight. These things will I do for them, and not forsake them.", "vulgate": "et ducam caecos in via quam nesciunt in semitis quas ignoraverunt ambulare eos faciam ponam tenebras coram eis in lucem et prava in recta haec verba feci eis et non dereliqui eos;", "brenton": "And I will bring the blind by a way that they knew not, and I will cause them to tread paths which they have not known: I will turn darkness into light for them, and crooked things into straight. These things will I do, and will not forsake them."}}, {"v": 17, "ref": "42:17", "o": "נָסֹ֤גוּ אָחוֹר֙ יֵבֹ֣שׁוּ בֹ֔שֶׁת הַ/בֹּטְחִ֖ים בַּ/פָּ֑סֶל הָ/אֹמְרִ֥ים לְ/מַסֵּכָ֖ה אַתֶּ֥ם אֱלֹהֵֽי/נוּ", "en": {"kjv": "They shall be turned back, they shall be greatly ashamed, that trust in graven images, that say to the molten images, Ye are our gods.", "web": "“Those who trust in engraved images, who tell molten images, ‘You are our gods’ will be turned back. They will be utterly disappointed.", "bsb": "But those who trust in idols and say to molten images, ‘You are our gods!’ will be turned back in utter shame.", "asv": "They shall be turned back, they shall be utterly put to shame, that trust in graven images, that say unto molten images, Ye are our gods.", "ylt": "Removed backward--utterly ashamed, Are those trusting in a graven image, Those saying to a molten image, `Ye are our gods.'", "dra": "They are turned back: let them be greatly confounded, that trust in a graven thing, that say to a molten thing: You are our god.", "bbe": "They will be turned back and be greatly shamed who put their hope in pictured images, who say to metal images, You are our gods.", "geneva": "They shall be turned backe: they shall be greatly ashamed, that trust in grauen images, and say to the molten images, Yee are our gods.", "wycliffe": "Thei ben turned abac; be thei schent with schenschipe, that trusten in a grauun ymage; whiche seien to a yotun ymage, Ye ben oure goddis.", "rotherham": "They have drawn back They turn very pale Who have been trusting in a graven image,—Who have been saying to a molten image, Ye, are our gods!", "darby": "They shall be turned back, they shall be covered with shame, that confide in graven images, that say to the molten images, Ye are ourgods.", "twenty": "", "jps": "They shall be turned back, greatly ashamed, that trust in graven images, that say unto molten images: 'Ye are our gods.'", "acv": "They shall be turned back, they shall be utterly put to shame, who trust in graven images, who say to molten images, Ye are our gods.", "anderson": "", "haweis": "", "noyes": "Then shall they be turned back, and be put to shame, Who trust in graven images; Who say to molten images, \"Ye are our gods!\"", "webster": "They shall be turned back, they shall be greatly ashamed, that trust in graven images, that say to the molten images, Ye [are] our gods.", "vulgate": "conversi sunt retrorsum confundantur confusione qui confidunt in sculptili qui dicunt conflatili vos dii nostri;", "brenton": "But they are turned back: be ye utterly ashamed that trust in graven images, who say to the molten images, Ye are our gods."}}, {"v": 18, "ref": "42:18", "o": "הַ/חֵרְשִׁ֖ים שְׁמָ֑עוּ וְ/הַ/עִוְרִ֖ים הַבִּ֥יטוּ לִ/רְאֽוֹת", "en": {"kjv": "Hear, ye deaf; and look, ye blind, that ye may see.", "web": "“Hear, you deaf, and look, you blind, that you may see.", "bsb": "Listen, you deaf ones; look, you blind ones, that you may see!", "asv": "Hear, ye deaf; and look, ye blind, that ye may see.", "ylt": "Ye deaf, hear; and ye blind, look to see.", "dra": "Hear, ye deaf, and, ye blind, behold that you may see.", "bbe": "Give ear, you whose ears are shut; and let your eyes be open, you blind, so that you may see.", "geneva": "Heare, ye deafe: and ye blinde, regarde, that ye may see.", "wycliffe": "Ye deef men, here; and ye blynde men, biholde to se.", "rotherham": "Ye deaf hear! And ye blind look around that ye may see,", "darby": "— Hear, ye deaf; and look, ye blind, that ye may see.", "twenty": "", "jps": "Hear, ye deaf, and look, ye blind, that ye may see.", "acv": "Hear, ye deaf, and look, ye blind, that ye may see.", "anderson": "", "haweis": "", "noyes": "Hear, O ye deaf! And look, ye blind, and see!", "webster": "Hear, ye deaf; and look, ye blind, that ye may see.", "vulgate": "surdi audite et caeci intuemini ad videndum;", "brenton": "Hear, ye deaf, and look up, ye blind, to see."}}, {"v": 19, "ref": "42:19", "o": "מִ֤י עִוֵּר֙ כִּ֣י אִם עַבְדִּ֔/י וְ/חֵרֵ֖שׁ כְּ/מַלְאָכִ֣/י אֶשְׁלָ֑ח מִ֤י עִוֵּר֙ כִּ/מְשֻׁלָּ֔ם וְ/עִוֵּ֖ר כְּ/עֶ֥בֶד יְהוָֽה", "en": {"kjv": "Who is blind, but my servant? or deaf, as my messenger that I sent? who is blind as he that is perfect, and blind as the Lord’s servant?", "web": "Who is blind, but my servant? Or who is as deaf as my messenger whom I send? Who is as blind as he who is at peace, and as blind as Yahweh’s servant?", "bsb": "Who is blind but My servant, or deaf like the messenger I am sending? Who is blind like My covenant partner, or blind like the servant of the LORD?", "asv": "Who is blind, but my servant? or deaf, as my messenger that I send? who is blind as he that is at peace with me, and blind as Jehovah’s servant?", "ylt": "Who is blind but My servant? And deaf as My messenger I send? Who is blind as he who is at peace, Yea, blind, as the servant of Jehovah?", "dra": "Who is blind, but my servant? or deaf, but he to whom I have sent my messengers? Who is blind, but he that is sold? or who is blind, but the servant of the Lord?", "bbe": "Who is blind, but my servant? who has his ears stopped, but he whom I send? who is blind as my true one, or who has his ears shut like the Lord's servant?", "geneva": "Who is blinde but my seruaunt? or deafe as my messenger, that I sent? who is blind as the perfit, and blinde as the Lordes seruant?", "wycliffe": "Who is blynd, no but my seruaunt? and deef, no but he to whom Y sente my messangeris? Who is blynd, no but he that is seeld? and who is blynd, no but the seruaunt of the Lord?", "rotherham": "Who is blind if not my Servant? Or deaf, like, my messenger whom I send? Who is, blind, like an intimate friend? Or blind like the Servant of Yahweh?", "darby": "Who is blind, but my servant? and deaf, as my messenger whom I sent? Who is blind as he in whom I have trusted, and blind as Jehovah's servant,", "twenty": "", "jps": "Who is blind, but My servant? Or deaf, as My messenger that I send? Who is blind as he that is wholehearted, and blind as HaShem'S servant?", "acv": "Who is blind, but my servant, or deaf, as my messenger that I send? Who is blind as he who is at peace with me, and blind as Jehovah's servant?", "anderson": "", "haweis": "", "noyes": "Who is blind, if not my servant? And who so deaf as my messenger, whom I send? Who so blind as the friend of God, So blind as the servant of Jehovah?", "webster": "Who [is] blind, but my servant? or deaf, as my messenger [that] I sent? who [is] blind as [he that is] perfect, and blind as the LORD'S servant?", "vulgate": "quis caecus nisi servus meus et surdus nisi ad quem nuntios meos misi quis caecus nisi qui venundatus est quis caecus nisi servus Domini;", "brenton": "And who is blind, but my servants? and deaf, but they that rule over them? yea, the servants of God have been made blind."}}, {"v": 20, "ref": "42:20", "o": "ראית רָא֥וֹת רַבּ֖וֹת וְ/לֹ֣א תִשְׁמֹ֑ר פָּק֥וֹחַ אָזְנַ֖יִם וְ/לֹ֥א יִשְׁמָֽע", "en": {"kjv": "Seeing many things, but thou observest not; opening the ears, but he heareth not.", "web": "You see many things, but don’t observe. His ears are open, but he doesn’t listen.", "bsb": "Though seeing many things, you do not keep watch. Though your ears are open, you do not hear.”", "asv": "Thou seest many things, but thou observest not; his ears are open, but he heareth not.", "ylt": "Seeing many things, and thou observest not, Opening ears, and he heareth not.", "dra": "Thou that seest many things, wilt thou not observe them? thou that hast ears open, wilt thou not hear?", "bbe": "Seeing much, but keeping nothing in mind; his ears are open, but there is no hearing.", "geneva": "Seeing many things, but thou keepest them not? opening the eares, but he heareth not?", "wycliffe": "Whether thou that seest many thingis, schalt not kepe? Whether thou that hast open eeris, schalt not here?", "rotherham": "Seeing many things, yet thou heedest not, Opening the ears yet he heareth not,", "darby": "— seeing many things, and thou observest not? With opened ears, he heareth not.", "twenty": "", "jps": "Seeing many things, thou observest not; opening the ears, he heareth not.", "acv": "Thou see many things, but thou do not observe. His ears are open, but he does not hear.", "anderson": "", "haweis": "", "noyes": "Thou seest many things, but regardest them not; Thou hast thine ears open, but hearest not!", "webster": "Seeing many things, but thou observest not; opening the ears, but he heareth not.", "vulgate": "qui vides multa nonne custodies qui apertas habes aures nonne audies;", "brenton": "Ye have often seen, and have not taken heed; your ears have been opened, and ye have not heard."}}, {"v": 21, "ref": "42:21", "o": "יְהוָ֥ה חָפֵ֖ץ לְמַ֣עַן צִדְק֑/וֹ יַגְדִּ֥יל תּוֹרָ֖ה וְ/יַאְדִּֽיר", "en": {"kjv": "The Lord is well pleased for his righteousness’ sake; he will magnify the law, and make it honourable.", "web": "It pleased Yahweh, for his righteousness’ sake, to magnify the law, and make it honorable.", "bsb": "The LORD was pleased, for the sake of His righteousness, to magnify His law and make it glorious.", "asv": "It pleased Jehovah, for his righteousness’ sake, to magnify the law, and make it honorable.", "ylt": "Jehovah hath delight for the sake of His righteousness, He magnifieth law, and maketh honourable.", "dra": "And the Lord was willing to sanctify him, and to magnify the law, and exalt it.", "bbe": "It was the Lord's pleasure, because of his righteousness, to make the teaching great and give it honour.", "geneva": "The Lord is willing for his righteousnesse sake that he may magnifie the Lawe, and exalt it.", "wycliffe": "And the Lord wolde, that he schulde halewe it, and magnefie the lawe, and enhaunse it.", "rotherham": "Yahweh, is well-pleased for his own righteousness’ sake, He magnifieth instruction and maketh it majestic.", "darby": "Jehovah had delight [in him] for his righteousness' sake: he hath magnified the law, and made it honourable.", "twenty": "", "jps": "HaShem was pleased, for His righteousness' sake, to make the teaching great and glorious.", "acv": "It pleased Jehovah, for his righteousness' sake, to magnify the law, and make it honorable.", "anderson": "", "haweis": "", "noyes": "It pleased Jehovah for his goodness’ sake To give him a law, great and glorious;", "webster": "The LORD is well pleased for his righteousness' sake; he will magnify the law, and make [it] honorable.", "vulgate": "et Dominus voluit ut sanctificaret eum et magnificaret legem et extolleret;", "brenton": "The Lord God has taken counsel that he might be justified, and might magnify his praise."}}, {"v": 22, "ref": "42:22", "o": "וְ/הוּא֮ עַם בָּז֣וּז וְ/שָׁסוּי֒ הָפֵ֤חַ בַּֽ/חוּרִים֙ כֻּלָּ֔/ם וּ/בְ/בָתֵּ֥י כְלָאִ֖ים הָחְבָּ֑אוּ הָי֤וּ לָ/בַז֙ וְ/אֵ֣ין מַצִּ֔יל מְשִׁסָּ֖ה וְ/אֵין אֹמֵ֥ר הָשַֽׁב", "en": {"kjv": "But this is a people robbed and spoiled; they are all of them snared in holes, and they are hid in prison houses: they are for a prey, and none delivereth; for a spoil, and none saith, Restore.", "web": "But this is a robbed and plundered people. All of them are snared in holes, and they are hidden in prisons. They have become captives, and no one delivers; and a plunder, and no one says, ‘Restore them!’", "bsb": "But this is a people plundered and looted, all trapped in caves or imprisoned in dungeons. They have become plunder with no one to rescue them, and loot with no one to say, “Send them back!”", "asv": "But this is a people robbed and plundered; they are all of them snared in holes, and they are hid in prison-houses: they are for a prey, and none delivereth; for a spoil, and none saith, Restore.", "ylt": "And this is a people seized and spoiled, Snared in holes--all of them, And in houses of restraint they were hidden, They have been for a prey, And there is no deliverer, A spoil, and none is saying, `Restore.'", "dra": "But this is a people that is robbed and wasted: they are all the snare of young men, and they are hid in the houses of prisons: they are made a prey, and there is none to deliver them: a spoil, and there is none that saith: Restore.", "bbe": "But this is a people whose property has been taken away from them by force; they are all taken in holes, and shut up in prisons: they are made prisoners, and no one makes them free; they are taken by force and no one says, Give them back.", "geneva": "But this people is robbed and spoiled, and shalbe all snared in dungeons, and they shalbe hid in prison houses: they shall be for a pray, and none shall deliuer: a spoile, and none shall say, Restore.", "wycliffe": "But thilke puple was rauyschid, and wastid; alle thei ben the snare of yonge men, and ben hid in the housis of prisouns. Thei ben maad in to raueyn, and noon is that delyuereth; in to rauyschyng, and noon is that seith, Yelde thou.", "rotherham": "But, that, is a people preyed upon and plundered, Snared in holes, all of them, And, in houses of restraint, concealed,—They have become a prey, and there is none to deliver,—A booty, and there is none to say—Restore!", "darby": "But this is a people robbed and spoiled; they are all of them snared in holes, and hidden in prison-houses; they are become a prey, and none delivereth, — a spoil, and none saith, Restore.", "twenty": "", "jps": "But this is a people robbed and spoiled, they are all of them snared in holes, and they are hid in prison-houses; they are for a prey, and none delivereth, for a spoil, and none saith: 'Restore.'", "acv": "But this is a people robbed and plundered. They are all of them snared in holes, and they are hid in prison-houses. They are for a prey, and none delivers, for a spoil, and none says, Restore.", "anderson": "", "haweis": "", "noyes": "And yet it is a robbed and plundered people; They are all of them bound in prisons, And hid in dungeons; They have become a spoil, and none delivereth; A prey, and none saith, \"Restore!\"", "webster": "But this [is] a people robbed and pillaged; [they are] all of them snared in holes, and they are hid in prison-houses; they are for a prey, and none delivereth; for a spoil, and none saith, Restore.", "vulgate": "ipse autem populus direptus et vastatus laqueus iuvenum omnes et in domibus carcerum absconditi sunt facti sunt in rapinam nec est qui eruat in direptionem et non est qui dicat redde;", "brenton": "And I beheld, and the people were spoiled and plundered: for there is a snare in the secret chambers everywhere, and in the houses also, where they have hidden them: they became a spoil, and there was no one that delivered the prey, and there was none who said, Restore."}}, {"v": 23, "ref": "42:23", "o": "מִ֥י בָ/כֶ֖ם יַאֲזִ֣ין זֹ֑את יַקְשִׁ֥ב וְ/יִשְׁמַ֖ע לְ/אָחֽוֹר", "en": {"kjv": "Who among you will give ear to this? who will hearken and hear for the time to come?", "web": "Who is there among you who will give ear to this? Who will listen and hear for the time to come?", "bsb": "Who among you will pay attention to this? Who will listen and obey hereafter?", "asv": "Who is there among you that will give ear to this? that will hearken and hear for the time to come?", "ylt": "Who among you giveth ear to this? Attendeth, and heareth afterwards.", "dra": "Who is there among you that will give ear to this, that will attend and hearken for times to come?", "bbe": "Who is there among you who will give ear to this? who will give attention to it for the time to come?", "geneva": "Who among you shall hearken to this, and take heede, and heare for afterwardes?", "wycliffe": "Who is among you, that herith this, perseyueth, and herkneth thingis to comynge?", "rotherham": "Who among you, will give ear to this,—Let him hearken and hear, for an aftertime?", "darby": "Who among you will give ear to this, [who] will hearken and hear what is to come?", "twenty": "", "jps": "Who among you will give ear to this? Who will hearken and hear for the time to come?", "acv": "Who is there among you that will give ear to this, that will hearken and hear for the time to come?", "anderson": "", "haweis": "", "noyes": "Who is there among you that will give ear to this, That will listen and attend for the time to come?", "webster": "Who among you will give ear to this? [who] will hearken, and hear for the time to come?", "vulgate": "quis est in vobis qui audiat hoc adtendat et auscultet futura;", "brenton": "Who is there among you that will give ear to these things? hearken ye to the things which are coming to pass."}}, {"v": 24, "ref": "42:24", "o": "מִֽי נָתַ֨ן ל/משוסה לִ/מְשִׁסָּ֧ה יַעֲקֹ֛ב וְ/יִשְׂרָאֵ֥ל לְ/בֹזְזִ֖ים הֲ/ל֣וֹא יְהוָ֑ה ז֚וּ חָטָ֣אנוּ ל֔/וֹ וְ/לֹֽא אָב֤וּ בִ/דְרָכָי/ו֙ הָל֔וֹךְ וְ/לֹ֥א שָׁמְע֖וּ בְּ/תוֹרָתֽ/וֹ", "en": {"kjv": "Who gave Jacob for a spoil, and Israel to the robbers? did not the Lord, he against whom we have sinned? for they would not walk in his ways, neither were they obedient unto his law.", "web": "Who gave Jacob as plunder, and Israel to the robbers? Didn’t Yahweh, he against whom we have sinned? For they would not walk in his ways, and they disobeyed his law.", "bsb": "Who gave Jacob up for spoil, and Israel to the plunderers? Was it not the LORD, against whom we have sinned? They were unwilling to walk in His ways, and they would not obey His law.", "asv": "Who gave Jacob for a spoil, and Israel to the robbers? did not Jehovah? he against whom we have sinned, and in whose ways they would not walk, neither were they obedient unto his law.", "ylt": "Who hath given Jacob for a spoil, And Israel to the spoilers? Is it not Jehovah--He against whom we sinned? Yea, they have not been willing in His ways to walk, Nor have they hearkened to His law.", "dra": "Who hath given Jacob for a spoil, and Israel to robbers? hath not the Lord himself, against whom we have sinned? And they would not walk in his ways, and they have not hearkened to his law.", "bbe": "Who gave up Jacob to those who took away his goods, and Israel to his attackers? Did not the Lord? he against whom they did wrong, and in whose ways they would not go, turning away from his teaching.", "geneva": "Who gaue Iaakob for a spoyle, and Israel to the robbers? Did not ye Lord, because we haue sinned against him? for they woulde not walke in his waies, neither be obedient vnto his Lawe.", "wycliffe": "Who yaf Jacob in to rauyschyng, and Israel to distrieris? Whether not the Lord? He it is, ayens whom thei synneden; and thei nolden go in hise weies, and thei herden not his lawe.", "rotherham": "Who gave, as a booty, Jacob. And, Israel, to them who were ready to take prey? Was it not, Yahweh? He against whom we have sinned, And they were not willing, in his ways, to walk, Neither hearkened they to his instruction?", "darby": "Who gave Jacob for a spoil, and Israel to the robbers? Did not Jehovah, he against whom we have sinned? And they would not walk in his ways, neither did they hearken unto his law.", "twenty": "", "jps": "Who gave Jacob for a spoil, and Israel to the robbers? Did not HaShem? He against whom we have sinned, and in whose ways they would not walk, neither were they obedient unto His law.", "acv": "Who gave Jacob for a spoil, and Israel to the robbers? Did not Jehovah? He against whom we have sinned, and in whose ways they would not walk, nor were they obedient to his law.", "anderson": "", "haweis": "", "noyes": "Who gave Jacob to be a spoil, And Israel to plunderers? Was it not Jehovah, against whom we sinned, In whose ways we would not walk, And whose laws we would not obey?", "webster": "Who gave Jacob for a spoil, and Israel to the robbers? did not the LORD, he against whom we have sinned? for they would not walk in his ways, neither were they obedient to his law.", "vulgate": "quis dedit in direptionem Iacob et Israhel vastantibus nonne Dominus ipse cui peccavimus et noluerunt in viis eius ambulare et non audierunt legem eius;", "brenton": "For what did he give to Jacob up to spoil, and Israel to them that plundered him? Did not God do it against whom they sinned? and they would not walk in his ways, nor hearken to his law."}}, {"v": 25, "ref": "42:25", "o": "וַ/יִּשְׁפֹּ֤ךְ עָלָי/ו֙ חֵמָ֣ה אַפּ֔/וֹ וֶ/עֱז֖וּז מִלְחָמָ֑ה וַ/תְּלַהֲטֵ֤/הוּ מִ/סָּבִיב֙ וְ/לֹ֣א יָדָ֔ע וַ/תִּבְעַר בּ֖/וֹ וְ/לֹא יָשִׂ֥ים עַל לֵֽב", "en": {"kjv": "Therefore he hath poured upon him the fury of his anger, and the strength of battle: and it hath set him on fire round about, yet he knew not; and it burned him, yet he laid it not to heart.", "web": "Therefore he poured the fierceness of his anger on him, and the strength of battle; and it set him on fire all around, but he didn’t know; and it burned him, but he didn’t take it to heart.”", "bsb": "So He poured out on them His furious anger and the fierceness of battle. It enveloped them in flames, but they did not understand; it consumed them, but they did not take it to heart.", "asv": "Therefore he poured upon him the fierceness of his anger, and the strength of battle; and it set him on fire round about, yet he knew not; and it burned him, yet he laid it not to heart.", "ylt": "And He poureth on him fury, His anger, and the strength of battle, And it setteth him on fire round about, And he hath not known, And it burneth against him, and he layeth it not to heart!", "dra": "And he hath poured out upon him the indignation of his fury, and a strong battle, and hath burnt him round about, and he knew not: and set him on fire, and he understood not.", "bbe": "For this reason he let loose on him the heat of his wrath, and his strength was like a flame; and it put fire round about him, but he did not see it; he was burned, but did not take it to heart.", "geneva": "Therefore hee hath powred vpon him his fierce wrath, and the strength of battell: and it set him on fire round about, and he knewe not, and it burned him vp, yet he considered not.", "wycliffe": "And he schedde out on hem the indignacioun of his strong veniaunce, and strong batel; and thei brenten it in cumpas, and it knewe not; and he brente it, and it vndurstood not.", "rotherham": "So he hath poured out, upon him, the glow of his anger, and the strength of battle; And it hath set him aflame round about, yet he knoweth it not, And it hath kindled upon him yet he layeth it not to heart.", "darby": "And he hath poured upon him the fury of his anger, and the strength of battle: and it set him on fire round about, yet he knew not; and it burned him, yet he took it not to heart.", "twenty": "", "jps": "Therefore He poured upon him the fury of His anger, and the strength of battle; and it set him on fire round about, yet he knew not, and it burned him, yet he laid it not to heart.", "acv": "Therefore he poured upon him the fierceness of his anger, and the strength of battle. And it set him on fire round about, yet he knew not. And it burned him, yet he laid it not to heart.", "anderson": "", "haweis": "", "noyes": "Therefore hath he poured out upon Israel the fury of his wrath, and the violence of war; It kindled a flame around about him, yet he did not regard it; It set him on fire, yet he laid it not to heart.", "webster": "Therefore he hath poured upon him the fury of his anger, and the strength of battle: and it hath set him on fire around, yet he knew not; and it burned him, yet he laid [it] not to heart.", "vulgate": "et effudit super eum indignationem furoris sui et forte bellum et conbusit eum in circuitu et non cognovit et succendit eum et non intellexit;", "brenton": "So he brought upon them the fury of his wrath; and the war, and those that burnt round about them, prevailed against them; yet no one of them knew it, neither did they lay it to heart."}}]}, {"c": 43, "verses": [{"v": 1, "ref": "43:1", "o": "וְ/עַתָּ֞ה כֹּֽה אָמַ֤ר יְהוָה֙ בֹּרַאֲ/ךָ֣ יַעֲקֹ֔ב וְ/יֹצֶרְ/ךָ֖ יִשְׂרָאֵ֑ל אַל תִּירָא֙ כִּ֣י גְאַלְתִּ֔י/ךָ קָרָ֥אתִי בְ/שִׁמְ/ךָ֖ לִ/י אָֽתָּה", "en": {"kjv": "But now thus saith the Lord that created thee, O Jacob, and he that formed thee, O Israel, Fear not: for I have redeemed thee, I have called thee by thy name; thou art mine.", "web": "But now thus says Yahweh who created you, Jacob, and he who formed you, Israel: “Don’t be afraid, for I have redeemed you. I have called you by your name. You are mine.", "bsb": "Now this is what the LORD says— He who created you, O Jacob, and He who formed you, O Israel: “Do not fear, for I have redeemed you; I have called you by your name; you are Mine!", "asv": "But now thus saith Jehovah that created thee, O Jacob, and he that formed thee, O Israel: Fear not, for I have redeemed thee; I have called thee by thy name, thou art mine.", "ylt": "And now, thus said Jehovah, Thy Creator, O Jacob, and thy Fashioner, O Israel, Be not afraid, for I have redeemed thee, I have called on thy name--thou art Mine.", "dra": "And now thus saith the Lord that created thee, O Jacob, and formed thee, O Israel: Fear not, for I have redeemed thee, and called thee by thy name: thou art mine.", "bbe": "But now, says the Lord your Maker, O Jacob, and your life-giver, O Israel: have no fear, for I have taken up your cause; naming you by your name, I have made you mine.", "geneva": "But nowe thus sayeth the Lord, that created thee, O Iaakob: and hee that formed thee, O Israel, Feare not: for I haue redeemed thee: I haue called thee by thy name, thou art mine.", "wycliffe": "And now the Lord God, makynge of nouyt thee, Jacob, and formynge thee, Israel, seith these thingis, Nyle thou drede, for Y ayenbouyte thee, and Y clepide thee bi thi name; thou art my seruaunt.", "rotherham": "Now, therefore, Thus, saith Yahweh—Creating thee, O Jacob, and Fashioning thee O Israel,—Do not fear, For I have redeemed thee, I have called thee by thy name. Mine, thou art!", "darby": "But now thus saith Jehovah, that created thee, O Jacob, and he that formed thee, O Israel: Fear not, for I have redeemed thee, I have called [thee] by thy name; thou art mine.", "twenty": "", "jps": "But now thus saith HaShem that created thee, O Jacob, and He that formed thee, O Israel: Fear not, for I have redeemed thee, I have called thee by thy name, thou art Mine.", "acv": "But now thus says Jehovah who created thee, O Jacob, and he who formed thee, O Israel: Fear not, for I have redeemed thee. I have called thee by thy name, Thou are mine.", "anderson": "", "haweis": "", "noyes": "But now thus saith Jehovah, that created thee, O Jacob, That formed thee, O Israel: Fear not, for I have redeemed thee; I have called thee by name; thou art mine!", "webster": "But now thus saith the LORD that created thee, O Jacob, and he that formed thee, O Israel, Fear not: for I have redeemed thee, I have called [thee] by thy name; thou [art] mine.", "vulgate": "et nunc haec dicit Dominus creans te Iacob et formans te Israhel noli timere quia redemi te et vocavi nomine tuo meus es tu;", "brenton": "And now thus saith the Lord God that made thee, O Jacob, and formed thee, O Israel, Fear not: for I have redeemed thee, I have called thee by thy name; thou art mine."}}, {"v": 2, "ref": "43:2", "o": "כִּֽי תַעֲבֹ֤ר בַּ/מַּ֨יִם֙ אִתְּ/ךָ אָ֔נִי וּ/בַ/נְּהָר֖וֹת לֹ֣א יִשְׁטְפ֑וּ/ךָ כִּֽי תֵלֵ֤ךְ בְּמוֹ אֵשׁ֙ לֹ֣א תִכָּוֶ֔ה וְ/לֶהָבָ֖ה לֹ֥א תִבְעַר בָּֽ/ךְ", "en": {"kjv": "When thou passest through the waters, I will be with thee; and through the rivers, they shall not overflow thee: when thou walkest through the fire, thou shalt not be burned; neither shall the flame kindle upon thee.", "web": "When you pass through the waters, I will be with you; and through the rivers, they will not overflow you. When you walk through the fire, you will not be burned, and flame will not scorch you.", "bsb": "When you pass through the waters, I will be with you; and when you go through the rivers, they will not overwhelm you. When you walk through the fire, you will not be scorched; the flames will not set you ablaze.", "asv": "When thou passest through the waters, I will be with thee; and through the rivers, they shall not overflow thee: when thou walkest through the fire, thou shalt not be burned, neither shall the flame kindle upon thee.", "ylt": "When thou passest into waters, I am with thee, And into floods, they do not overflow thee, When thou goest into fire, thou art not burnt, And a flame doth not burn against thee.", "dra": "When thou shalt pass through the waters, I will be with thee, and the rivers shall not cover thee: when thou shalt walk in the fire, thou shalt not be burnt, and the flames shall not burn in thee:", "bbe": "When you go through the waters, I will be with you; and through the rivers, they will not go over you: when you go through the fire, you will not be burned; and the flame will have no power over you.", "geneva": "When thou passest through the waters, I wil be with thee, and through the floods, that they doe not ouerflowe thee. When thou walkest through the very fire, thou shalt not be burnt, neither shall the flame kindle vpon thee.", "wycliffe": "Whanne thou schalt go bi watris, Y schal be with thee, and floodis schulen not hile thee; whanne thou schalt go in fier, thou schalt not be brent, and flawme schal not brenne in thee.", "rotherham": "When thou passest through the waters, with thee, I am, Or, through the rivers, they shall not overflow thee,—When thou walkest through fire, thou shall not be scorched, And, a flame, shall not kindle upon thee;", "darby": "When thou passest through the waters, I [will be] with thee; and through the rivers, they shall not overflow thee; when thou walkest through the fire, thou shalt not be burned, neither shall the flame kindle upon thee.", "twenty": "", "jps": "When thou passest through the waters, I will be with thee, and through the rivers, they shall not overflow thee; when thou walkest through the fire, thou shalt not be burned, neither shall the flame kindle upon thee.", "acv": "When thou pass through the waters, I will be with thee, and through the rivers, they shall not overflow thee. When thou walk through the fire, thou shall not be burned, nor shall the flame kindle upon thee.", "anderson": "", "haweis": "", "noyes": "When thou passest through waters, I will be with thee; And through rivers, they shall not overflow thee; When thou walkest through fire, thou shalt not be burned, And the flame shall not consume thee.", "webster": "When thou passest through the waters, I [will be] with thee; and through the rivers, they shall not overflow thee: when thou walkest through the fire, thou shalt not be burned; neither shall the flame kindle upon thee.", "vulgate": "cum transieris per aquas tecum ero et flumina non operient te cum ambulaveris in igne non conbureris et flamma non ardebit in te;", "brenton": "And if thou pass through water, I am with thee; and the rivers shall not overflow thee: and if thou go through fire, thou shalt not be burned; the flame shall not burn thee."}}, {"v": 3, "ref": "43:3", "o": "כִּ֗י אֲנִי֙ יְהוָ֣ה אֱלֹהֶ֔י/ךָ קְד֥וֹשׁ יִשְׂרָאֵ֖ל מוֹשִׁיעֶ֑/ךָ נָתַ֤תִּי כָפְרְ/ךָ֙ מִצְרַ֔יִם כּ֥וּשׁ וּ/סְבָ֖א תַּחְתֶּֽי/ךָ", "en": {"kjv": "For I am the Lord thy God, the Holy One of Israel, thy Saviour: I gave Egypt for thy ransom, Ethiopia and Seba for thee.", "web": "For I am Yahweh your God, the Holy One of Israel, your Savior. I have given Egypt as your ransom, Ethiopia and Seba in your place.", "bsb": "For I am the LORD your God, the Holy One of Israel, your Savior; I give Egypt for your ransom, Cush and Seba in your place.", "asv": "For I am Jehovah thy God, the Holy One of Israel, thy Saviour; I have given Egypt as thy ransom, Ethiopia and Seba in thy stead.", "ylt": "For I--Jehovah thy God, The Holy One of Israel, thy Saviour, I have appointed Egypt thine atonement, Cush and Seba in thy stead.", "dra": "For I am the Lord thy God, the Holy One of Israel, thy Saviour: I have given Egypt for thy atonement, Ethiopia and Saba for thee.", "bbe": "For I am the Lord your God, the Holy One of Israel, your saviour; I have given Egypt as a price for you, Ethiopia and Seba for you.", "geneva": "For I am the Lord thy God, the holy one of Israel, thy Sauiour: I gaue Egypt for thy ransome, Ethiopia, and Seba for thee.", "wycliffe": "For Y am thi Lord God, the hooli of Israel, thi sauyour. I yaf thi merci Egipt; Ethiopie and Saba for thee.", "rotherham": "For, I,—Yahweh, am, Thy God, The Holy One of Israel Ready to save thee,—I have given, as thy ransom, Egypt, Ethiopia and Seba, in thy stead.", "darby": "For I [am] Jehovah thyGod, the Holy One of Israel, thy Saviour: I gave Egypt for thy ransom, Ethiopia and Seba for thee.", "twenty": "", "jps": "For I am HaShem thy G-d, The Holy One of Israel, thy Saviour; I have given Egypt as thy ransom, Ethiopia and Seba for thee.", "acv": "For I am Jehovah thy God, the Holy One of Israel, thy Savior. I have given Egypt as thy ransom, Ethiopia and Seba in thy stead.", "anderson": "", "haweis": "", "noyes": "For I am Jehovah, thy God, The Holy One of Israel, thy saviour. I will give Egypt for thy ransom, Ethiopia and Seba for thee;", "webster": "For I [am] the LORD thy God, the Holy One of Israel, thy Savior: I gave Egypt [for] thy ransom, Cush and Seba for thee.", "vulgate": "quia ego Dominus Deus tuus Sanctus Israhel salvator tuus dedi propitiationem tuam Aegyptum Aethiopiam et Saba pro te;", "brenton": "For I am the Lord thy God, the Holy One of Israel, that saves thee: I have made Egypt and Ethiopia thy ransom, and given Soene for thee."}}, {"v": 4, "ref": "43:4", "o": "מֵ/אֲשֶׁ֨ר יָקַ֧רְתָּ בְ/עֵינַ֛/י נִכְבַּ֖דְתָּ וַ/אֲנִ֣י אֲהַבְתִּ֑י/ךָ וְ/אֶתֵּ֤ן אָדָם֙ תַּחְתֶּ֔י/ךָ וּ/לְאֻמִּ֖ים תַּ֥חַת נַפְשֶֽׁ/ךָ", "en": {"kjv": "Since thou wast precious in my sight, thou hast been honourable, and I have loved thee: therefore will I give men for thee, and people for thy life.", "web": "Since you have been precious and honored in my sight, and I have loved you; therefore I will give people in your place, and nations instead of your life.", "bsb": "Because you are precious and honored in My sight, and because I love you, I will give men in exchange for you and nations in place of your life.", "asv": "Since thou hast been precious in my sight, and honorable, and I have loved thee; therefore will I give men in thy stead, and peoples instead of thy life.", "ylt": "Since thou wast precious in Mine eyes, Thou wast honoured, and I have loved thee, And I appoint men in thy stead, And peoples instead of thy life.", "dra": "Since thou becamest honourable in my eyes, thou art glorious: I have loved thee, and I will give men for thee, and people for thy life.", "bbe": "Because of your value in my eyes, you have been honoured, and loved by me; so I will give men for you, and peoples for your life.", "geneva": "Because thou wast precious in my sight, and thou wast honourable, and I loued thee, therefore will I giue man for thee, and people for thy sake.", "wycliffe": "Sithen thou art maad onourable, and gloriouse in myn iyen; Y louyde thee, and Y schal yyue men for thee, and puplis for thi soule.", "rotherham": "Because thou art precious in mine eyes, art honoured And, I, love thee,—And will give mankind, in thy stead, Yea, peoples, for thy life,", "darby": "Since thou wast precious in my sight, thou hast been honourable, and I have loved thee; and I will give men for thee, and peoples for thy life.", "twenty": "", "jps": "Since thou art precious in My sight, and honourable, and I have loved thee; therefore will I give men for thee, and peoples for thy life.", "acv": "Since thou have been precious in my sight, and honorable, and I have loved thee, therefore I will give men in thy stead, and peoples instead of thy life.", "anderson": "", "haweis": "", "noyes": "Because thou art precious in my sight, Because thou art honored, and I love thee, Therefore will I give men for thee, And nations for thy life.", "webster": "Since thou hast been precious in my sight, thou hast been honorable, and I have loved thee: therefore will I give men for thee, and people for thy life.", "vulgate": "ex quo honorabilis factus es in oculis meis et gloriosus ego dilexi te et dabo homines pro te et populos pro anima tua;", "brenton": "Since thou becamest precious in my sight, thou hast become glorious, and I have loved thee: and I will give men for thee, and princes for thy life."}}, {"v": 5, "ref": "43:5", "o": "אַל תִּירָ֖א כִּ֣י אִתְּ/ךָ אָ֑נִי מִ/מִּזְרָח֙ אָבִ֣יא זַרְעֶ֔/ךָ וּ/מִֽ/מַּעֲרָ֖ב אֲקַבְּצֶֽ/ךָּ", "en": {"kjv": "Fear not: for I am with thee: I will bring thy seed from the east, and gather thee from the west;", "web": "Don’t be afraid; for I am with you. I will bring your seed from the east, and gather you from the west.", "bsb": "Do not be afraid, for I am with you; I will bring your offspring from the east and gather you from the west.", "asv": "Fear not; for I am with thee: I will bring thy seed from the east, and gather thee from the west;", "ylt": "Be not afraid, for I am with thee, From the east I bring in thy seed, And from the west I gather thee.", "dra": "Fear not, for I am with thee: I will bring thy seed from the east, and gather thee from the west.", "bbe": "Have no fear, for I am with you: I will take your seed from the east, and get you together from the west;", "geneva": "Feare not, for I am with thee: I will bring thy seede from the East, and gather thee from the West.", "wycliffe": "Nyle thou drede, for Y am with thee; Y schal brynge thi seed fro the eest, and Y schal gadere thee togidere fro the west.", "rotherham": "Do not fear for, with thee, I am,—From the East, will I bring in thy seed, And, from the West, will I gather thee:", "darby": "Fear not, for I [am] with thee: I will bring thy seed from the east, and gather thee from the west;", "twenty": "", "jps": "Fear not, for I am with thee; I will bring thy seed from the east, and gather thee from the west;", "acv": "Fear not, for I am with thee. I will bring thy seed from the east, and gather thee from the west.", "anderson": "", "haweis": "", "noyes": "Fear not, for I am with thee! I will bring thy children from the East, And gather thee from the West.", "webster": "Fear not: for I [am] with thee: I will bring thy seed from the east, and gather thee from the west;", "vulgate": "noli timere quoniam tecum ego sum ab oriente adducam semen tuum et ab occidente congregabo te;", "brenton": "Fear not; for I am with thee: I will bring thy seed from the east, and will gather thee from the west."}}, {"v": 6, "ref": "43:6", "o": "אֹמַ֤ר לַ/צָּפוֹן֙ תֵּ֔נִי וּ/לְ/תֵימָ֖ן אַל תִּכְלָ֑אִי הָבִ֤יאִי בָנַ/י֙ מֵ/רָח֔וֹק וּ/בְנוֹתַ֖/י מִ/קְצֵ֥ה הָ/אָֽרֶץ", "en": {"kjv": "I will say to the north, Give up; and to the south, Keep not back: bring my sons from far, and my daughters from the ends of the earth;", "web": "I will tell the north, ‘Give them up!’ and tell the south, ‘Don’t hold them back! Bring my sons from far, and my daughters from the ends of the earth—", "bsb": "I will say to the north, ‘Give them up!’ and to the south, ‘Do not hold them back!’ Bring My sons from afar, and My daughters from the ends of the earth—", "asv": "I will say to the north, Give up; and to the south, Keep not back; bring my sons from far, and my daughters from the end of the earth;", "ylt": "I am saying to the north, `Give up,' And to the south, `Restrain not.' Bring in My sons from afar, And My daughters from the end of the earth.", "dra": "I will say to the north: Give up: and to the south: Keep not back: bring my sons from afar, and my daughters from the ends of the earth.", "bbe": "I will say to the north, Give them up; and to the south, Do not keep them back; send back my sons from far, and my daughters from the end of the earth;", "geneva": "I will say to the North, Giue: and to the South, Keepe not backe: bring my sonnes from farre, and my daughters from the ends of the earth.", "wycliffe": "Y schal seie to the north, Yyue thou, and to the south, Nyle thou forbede; brynge thou my sones fro afer, and my douytris fro the laste partis of erthe.", "rotherham": "I will say to the North Give up! And to the South Do not withhold! Bring in My sons from far, and My daughters from the end of the earth;", "darby": "I will say to the north, Give up; and to the south, Keep not back: bring my sons from afar, and my daughters from the end of the earth,", "twenty": "", "jps": "I will say to the north: 'Give up,' and to the south: 'Keep not back, bring My sons from far, and My daughters from the end of the earth;", "acv": "I will say to the north, Give up, and to the south, Keep not back. Bring my sons from far, and my daughters from the end of the earth,", "anderson": "", "haweis": "", "noyes": "I will say to the North, \"Give them up!\" And to the South, \"Withhold them not! Bring my sons from afar, And my daughters from the ends of the earth;", "webster": "I will say to the north, Give up; and to the south, Keep not back: bring my sons from far, and my daughters from the ends of the earth;", "vulgate": "dicam aquiloni da et austro noli prohibere adfer filios meos de longinquo et filias meas ab extremis terrae;", "brenton": "I will say to the north, Bring; and to the south, Keep not back; bring my sons from the land afar off, and my daughters from the ends of the earth;"}}, {"v": 7, "ref": "43:7", "o": "כֹּ֚ל הַ/נִּקְרָ֣א בִ/שְׁמִ֔/י וְ/לִ/כְבוֹדִ֖/י בְּרָאתִ֑י/ו יְצַרְתִּ֖י/ו אַף עֲשִׂיתִֽי/ו", "en": {"kjv": "Even every one that is called by my name: for I have created him for my glory, I have formed him; yea, I have made him.", "web": "everyone who is called by my name, and whom I have created for my glory, whom I have formed, yes, whom I have made.’”", "bsb": "everyone called by My name and created for My glory, whom I have indeed formed and made.”", "asv": "every one that is called by my name, and whom I have created for my glory, whom I have formed, yea, whom I have made.", "ylt": "Every one who is called by My name, Even for My honour I have created him, I have formed him, yea, I have made him.", "dra": "And every one that calleth upon my name, I have created him for my glory. I have formed him, and made him.", "bbe": "Every one who is named by my name, and whom I have made for my glory, who has been formed and designed by me.", "geneva": "Euery one shall be called by my Name: for I created him for my glorie, formed him and made him.", "wycliffe": "And ech that clepith my name to help, in to my glorie Y made hym of nouyt; Y fourmyde hym, and made hym.", "rotherham": "Every one who is called by my Name, Whom for mine own glory, I have created—formed—yea, made!", "darby": "every one that is called by my name, and whom I have created for my glory: I have formed him, yea, I have made him.", "twenty": "", "jps": "Every one that is called by My name, and whom I have created for My glory, I have formed him, yea, I have made him.'", "acv": "everyone who is called by my name, and whom I have created for my glory, whom I have formed, yea, whom I have made.", "anderson": "", "haweis": "", "noyes": "Every one that is called by my name, That I have created for my glory, That I have formed and made!\"", "webster": "[Even] every one that is called by my name: for I have created him for my glory, I have formed him; verily, I have made him.", "vulgate": "et omnem qui invocat nomen meum in gloriam meam creavi eum et formavi eum et feci eum;", "brenton": "even all who are called by my name: for I have prepared him for my glory, and I have formed him, and have made him:"}}, {"v": 8, "ref": "43:8", "o": "הוֹצִ֥יא עַם עִוֵּ֖ר וְ/עֵינַ֣יִם יֵ֑שׁ וְ/חֵרְשִׁ֖ים וְ/אָזְנַ֥יִם לָֽ/מוֹ", "en": {"kjv": "Bring forth the blind people that have eyes, and the deaf that have ears.", "web": "Bring out the blind people who have eyes, and the deaf who have ears.", "bsb": "Bring out a people who have eyes but are blind, and who have ears but are deaf.", "asv": "Bring forth the blind people that have eyes, and the deaf that have ears.", "ylt": "He brought out a blind people who have eyes, And deaf ones who have ears.", "dra": "Bring forth the people that are blind, and have eyes: that are deaf, and have ears.", "bbe": "Send out the blind people who have eyes, and those who have ears, but they are shut.", "geneva": "I will bring foorth the blinde people, and they shall haue eyes, and the deafe, and they shall haue eares.", "wycliffe": "Lede thou forth the blynde puple, and hauynge iyen; the deef puple, and eeris ben to it.", "rotherham": "Bring forth A blind people that have, eyes, and A deaf, that have, ears.", "darby": "Bring forth the blind people that have eyes, and the deaf that have ears.", "twenty": "", "jps": "The blind people that have eyes shall be brought forth, and the deaf that have ears.", "acv": "Bring forth the blind people who have eyes, and the deaf who have ears.", "anderson": "", "haweis": "", "noyes": "Bring forth the blind people, having eyes, And the deaf, having ears.", "webster": "Bring forth the blind people that have eyes, and the deaf that have ears.", "vulgate": "educ foras populum caecum et oculos habentem surdum et aures ei sunt;", "brenton": "and I have brought forth the blind people; for their eyes are alike blind, and they that have ears are deaf."}}, {"v": 9, "ref": "43:9", "o": "כָּֽל הַ/גּוֹיִ֞ם נִקְבְּצ֣וּ יַחְדָּ֗ו וְ/יֵאָֽסְפוּ֙ לְאֻמִּ֔ים מִ֤י בָ/הֶם֙ יַגִּ֣יד זֹ֔את וְ/רִֽאשֹׁנ֖וֹת יַשְׁמִיעֻ֑/נוּ יִתְּנ֤וּ עֵֽדֵי/הֶם֙ וְ/יִצְדָּ֔קוּ וְ/יִשְׁמְע֖וּ וְ/יֹאמְר֥וּ אֱמֶֽת", "en": {"kjv": "Let all the nations be gathered together, and let the people be assembled: who among them can declare this, and shew us former things? let them bring forth their witnesses, that they may be justified: or let them hear, and say, It is truth.", "web": "Let all the nations be gathered together, and let the peoples be assembled. Who among them can declare this, and show us former things? Let them bring their witnesses, that they may be justified; or let them hear, and say, “That is true.”", "bsb": "All the nations gather together and the peoples assemble. Who among them can declare this, and proclaim to us the former things? Let them present their witnesses to vindicate them, so that others may hear and say, “It is true.”", "asv": "Let all the nations be gathered together, and let the peoples be assembled: who among them can declare this, and show us former things? let them bring their witnesses, that they may be justified; or let them hear, and say, It is truth.", "ylt": "All the nations have been gathered together, And the peoples are assembled, Who among them declareth this, And former things causeth us to hear? They give their witnesses, And they are declared righteous, And they hear and say, `Truth.'", "dra": "All the nations are assembled together, and the tribes are gathered: who among you can declare this, and shall make us hear the former things? let them bring forth their witnesses, let them be justified, and hear, and say: It is truth.", "bbe": "Let all the nations come together, and let the peoples be present: who among them is able to make this clear, and give us word of earlier things? let their witnesses come forward, so that they may be seen to be true, and that they may give ear, and say, It is true.", "geneva": "Let all the nations be gathered together, and let the people be assembled: who among them can declare this and shewe vs former things? let them bring foorth their witnesses, that they may be iustified: but let them heare, and say, It is truth.", "wycliffe": "Alle hethene men ben gaderid togidere, and lynagis be gaderid togidere. Who among you, who schal telle this, and schal make you to here tho thingis, that ben the firste? yyue thei witnessis of hem, and be thei iustified, and here thei, and seie.", "rotherham": "All the nations, are gathered together Yea there is an assembling of peoples, Who among them, can tell this, And things in advance, can let us hear? Let them set forth their witnesses that they may get their right, Or let them hear, and say Truth!", "darby": "Let all the nations be gathered together, and let the peoples be assembled: who among them declareth this, or causeth us to hear former things? let them bring forth their witnesses, that they may be justified; or let them hear, and say, [It is] truth.", "twenty": "", "jps": "All the nations are gathered together, and the peoples are assembled; who among them can declare this, and announce to us former things? Let them bring their witnesses, that they may be justified; and let them hear, and say: 'It is truth.'", "acv": "Let all the nations be gathered together, and let the peoples be assembled. Who among them can declare this, and show us former things? Let them bring their witnesses that they may be justified, or let them hear, and say, It is truth.", "anderson": "", "haweis": "", "noyes": "Let all the nations be gathered together, And the kingdoms be assembled! Who among them hath declared this, And can show us former predictions? Let them produce their witnesses that they are right; That men may hear, and say, It is true!", "webster": "Let all the nations be collected, and let the people be assembled: who among them can declare this, and show us former things? let them bring forth their witnesses, that they may be justified: or let them hear, and say, [It is] truth.", "vulgate": "omnes gentes congregatae sunt simul et collectae sunt tribus quis in vobis adnuntiet istud et quae prima sunt audire nos faciat dent testes eorum et iustificentur et audiant et dicant vere;", "brenton": "All the nations are gathered together, and princes shall be gathered out of them: who will declare these things? or who will declare to you things from the beginning? let them bring forth their witnesses, and be justified; and let them hear, and declare the truth."}}, {"v": 10, "ref": "43:10", "o": "אַתֶּ֤ם עֵדַ/י֙ נְאֻם יְהוָ֔ה וְ/עַבְדִּ֖/י אֲשֶׁ֣ר בָּחָ֑רְתִּי לְמַ֣עַן תֵּ֠דְעוּ וְ/תַאֲמִ֨ינוּ לִ֤/י וְ/תָבִ֨ינוּ֙ כִּֽי אֲנִ֣י ה֔וּא לְ/פָנַ/י֙ לֹא נ֣וֹצַר אֵ֔ל וְ/אַחֲרַ֖/י לֹ֥א יִהְיֶֽה", "en": {"kjv": "Ye are my witnesses, saith the Lord, and my servant whom I have chosen: that ye may know and believe me, and understand that I am he: before me there was no God formed, neither shall there be after me.", "web": "“You are my witnesses,” says Yahweh, “With my servant whom I have chosen; that you may know and believe me, and understand that I am he. Before me there was no God formed, neither will there be after me.", "bsb": "“You are My witnesses,” declares the LORD, “and My servant whom I have chosen, so that you may consider and believe Me and understand that I am He. Before Me no god was formed, and after Me none will come.", "asv": "Ye are my witnesses, saith Jehovah, and my servant whom I have chosen; that ye may know and believe me, and understand that I am he: before me there was no God formed, neither shall there be after me.", "ylt": "Ye are My witnesses, an affirmation of Jehovah, And My servant whom I have chosen, So that ye know and give credence to Me, And understand that I am He, Before Me there was no God formed, And after Me there is none.", "dra": "You are my witnesses, saith the Lord, and my servant whom I have chosen: that you may know, and believe me, and understand that I myself am. Before me there was no God formed, and after me there shall be none.", "bbe": "You are my witnesses, says the Lord, and my servant whom I have taken for myself: so that you may see and have faith in me, and that it may be clear to you that I am he; before me there was no God formed, and there will not be after me.", "geneva": "You are my witnesses, saith the Lord, and my seruant, whom I haue chosen: therefore yee shall knowe and beleeue me and yee shall vnderstand that I am: before me there was no God formed, neither shall there be after me.", "wycliffe": "Verili ye ben my witnessis, seith the Lord, and my seruaunt, whom Y chees; that ye wite, and bileue to me, and vndurstonde, for Y mysilf am; bifore me is no God formere, and after me schal noon be.", "rotherham": "Ye, are my witnesses Declareth Yahweh, And my Servant, whom I have chosen,—That ye may take note—and believe me, And perceive that, I, am He, Before me, was not formed a GOD, Nor after me, shall one come into being:", "darby": "Ye are my witnesses, saith Jehovah, and my servant whom I have chosen; that ye may know and believe me, and understand that I [am] HE: before me there was noGod formed, neither shall there be after me.", "twenty": "", "jps": "Ye are My witnesses, saith HaShem, and My servant whom I have chosen; that ye may know and believe Me, and understand that I am He; before Me there was no G-d formed, neither shall any be after Me.", "acv": "Ye are my witnesses, says Jehovah, and my servant whom I have chosen, that ye may know and believe me, and understand that I am he. Before me there was no God formed, nor shall there be after me.", "anderson": "", "haweis": "", "noyes": "Ye are my witnesses, saith Jehovah, And my servant whom I have chosen, That ye may know and believe me, And understand that I am He. Before me was no god formed, And after me there shall be none.", "webster": "Ye [are] my witnesses, saith the LORD, and my servant whom I have chosen: that ye may know and believe me, and understand that I [am] he: before me there was no god formed, neither shall there be after me.", "vulgate": "vos testes mei dicit Dominus et servus meus quem elegi ut sciatis et credatis mihi et intellegatis quia ego ipse sum ante me non est formatus deus et post me non erit;", "brenton": "Be ye my witnesses, and I too am a witness, saith the Lord God, and my servant whom I have chosen: that ye may know, and believe, and understand that I am he: before me there was no other God, and after me there shall be none."}}, {"v": 11, "ref": "43:11", "o": "אָנֹכִ֥י אָנֹכִ֖י יְהוָ֑ה וְ/אֵ֥ין מִ/בַּלְעָדַ֖/י מוֹשִֽׁיעַ", "en": {"kjv": "I, even I, am the Lord; and beside me there is no saviour.", "web": "I myself am Yahweh; and besides me there is no savior.", "bsb": "I, yes I, am the LORD, and there is no Savior but Me.", "asv": "I, even I, am Jehovah; and besides me there is no saviour.", "ylt": "I--I am Jehovah, And besides Me there is no saviour.", "dra": "I am, I am the Lord: and there is no saviour besides me.", "bbe": "I, even I, am the Lord; and there is no saviour but me.", "geneva": "I, euen I am the Lord, and beside me there is no Sauiour.", "wycliffe": "Y am, Y am the Lord, and with out me is no sauyour.", "rotherham": "I—I, am Yahweh,—And there is none besides me ready to save:", "darby": "I, I [am] Jehovah; and besides me there is no saviour.", "twenty": "", "jps": "I, even I, am HaShem; and beside Me there is no saviour.", "acv": "I, even I, am Jehovah, and besides me there is no savior.", "anderson": "", "haweis": "", "noyes": "I, I am Jehovah, And besides me there is no saviour.", "webster": "I, [even] I, [am] the LORD; and besides me [there is] no savior.", "vulgate": "ego sum ego sum Dominus et non est absque me salvator;", "brenton": "I am God; and beside me there is no Saviour."}}, {"v": 12, "ref": "43:12", "o": "אָנֹכִ֞י הִגַּ֤דְתִּי וְ/הוֹשַׁ֨עְתִּי֙ וְ/הִשְׁמַ֔עְתִּי וְ/אֵ֥ין בָּ/כֶ֖ם זָ֑ר וְ/אַתֶּ֥ם עֵדַ֛/י נְאֻם יְהוָ֖ה וַֽ/אֲנִי אֵֽל", "en": {"kjv": "I have declared, and have saved, and I have shewed, when there was no strange god among you: therefore ye are my witnesses, saith the Lord, that I am God.", "web": "I have declared, I have saved, and I have shown; and there was no strange god among you. Therefore you are my witnesses”, says Yahweh, “and I am God.", "bsb": "I alone decreed and saved and proclaimed— I, and not some foreign god among you. So you are My witnesses,” declares the LORD, “that I am God.", "asv": "I have declared, and I have saved, and I have showed; and there was no strange god among you: therefore ye are my witnesses, saith Jehovah, and I am God.", "ylt": "I--I declared, and saved, and proclaimed, And there is no stranger with you, And ye are My witnesses, an affirmation of Jehovah, And I am God.", "dra": "I have declared, and have saved. I have made it heard, and there was no strange one among you. You are my witnesses, saith the Lord, and I am God.", "bbe": "I gave the word, and made it clear, and there was no strange god among you: for this reason you are my witnesses, says the Lord.", "geneva": "I haue declared, and I haue saued, and I haue shewed, when there was no strange god among you: therefore you are my witnesses, sayeth the Lord, that I am God.", "wycliffe": "I telde, and sauyde; Y made heryng, and noon alien God was among you. Ye ben my witnessis, seith the Lord;", "rotherham": "I, have told—and will save, and make known, That there is among you no strange one; And, ye, are my witnesses, Declareth Yahweh That, I, am GOD.", "darby": "It is I that have declared, and have saved, and have shewed, when there was no strange [god] among you; and ye are my witnesses, saith Jehovah, that I [am]God.", "twenty": "", "jps": "I have declared, and I have saved, and I have announced, and there was no strange god among you; therefore ye are My witnesses, saith HaShem, and I am G-d.", "acv": "I have declared, and I have saved, and I have shown, and there was no strange god among you. Therefore ye are my witnesses, says Jehovah, and I am God.", "anderson": "", "haweis": "", "noyes": "I have declared and have saved; I made it known, when there was no strange god among you; Ye are my witnesses, saith Jehovah, That I am God.", "webster": "I have declared, and have saved, and I have shown, when [there was] no strange [god] among you: therefore ye [are] my witnesses, saith the LORD, that I [am] God.", "vulgate": "ego adnuntiavi et salvavi auditum feci et non fuit in vobis alienus vos testes mei dicit Dominus et ego Deus;", "brenton": "I have declared, and have saved; I have reproached, and there was no strange god among you: ye are my witnesses, and I am the Lord God,"}}, {"v": 13, "ref": "43:13", "o": "גַּם מִ/יּוֹם֙ אֲנִ֣י ה֔וּא וְ/אֵ֥ין מִ/יָּדִ֖/י מַצִּ֑יל אֶפְעַ֖ל וּ/מִ֥י יְשִׁיבֶֽ/נָּה", "en": {"kjv": "Yea, before the day was I am he; and there is none that can deliver out of my hand: I will work, and who shall let it?", "web": "Yes, since the day was I am he; and there is no one who can deliver out of my hand. I will work, and who can hinder it?”", "bsb": "Even from eternity I am He, and none can deliver out of My hand. When I act, who can reverse it?”", "asv": "Yea, since the day was I am he; and there is none that can deliver out of my hand: I will work, and who can hinder it?", "ylt": "Even from the day I am He, And there is no deliverer from My hand, I work, and who doth turn it back?", "dra": "And from the beginning I am the same, and there is none that can deliver out of my hind: I will work, and who shall turn it away?", "bbe": "From time long past I am God, and from this day I am he: there is no one who is able to take you out of my hand: when I undertake a thing, by whom will my purpose be changed?", "geneva": "Yea, before the day was, I am, and there is none that can deliuer out of mine hand: I will doe it, and who shall let it?", "wycliffe": "and Y am God fro the bigynnyng, Y my silf am, and noon is that delyuerith fro myn hoond; Y schal worche, and who schal distrie it?", "rotherham": "Even from To-day, I, am He, And none, out of my hand, can deliver,—I work and who reverseth?", "darby": "Yea, since the day was, I [am] HE, and there is none that delivereth out of my hand: I will work, and who shall hinder it?", "twenty": "", "jps": "Yea, since the day was I am He, and there is none that can deliver out of My hand; I will work, and who can reverse it?", "acv": "Yea, since the day was I am he, and there is none that can deliver out of my hand. I will work, and who can hinder it?", "anderson": "", "haweis": "", "noyes": "Even from the beginning of time I have been He, And none can rescue from my hand; I undertake, and who can hinder?", "webster": "Yes, before the day [was], I [am] he; and [there is] none that can deliver out of my hand: I will work, and who shall hinder it?", "vulgate": "et ab initio ego ipse et non est qui de manu mea eruat operabor et quis avertet illud;", "brenton": "even from the beginning; and there is none that can deliver out of my hands: I will work, and who shall turn it back?"}}, {"v": 14, "ref": "43:14", "o": "כֹּֽה אָמַ֧ר יְהוָ֛ה גֹּאַלְ/כֶ֖ם קְד֣וֹשׁ יִשְׂרָאֵ֑ל לְמַעַנְ/כֶ֞ם שִׁלַּ֣חְתִּי בָבֶ֗לָ/ה וְ/הוֹרַדְתִּ֤י בָֽ/רִיחִים֙ כֻּלָּ֔/ם וְ/כַשְׂדִּ֖ים בָּ/אֳנִיּ֥וֹת רִנָּתָֽ/ם", "en": {"kjv": "Thus saith the Lord, your redeemer, the Holy One of Israel; For your sake I have sent to Babylon, and have brought down all their nobles, and the Chaldeans, whose cry is in the ships.", "web": "Thus says Yahweh, your Redeemer, the Holy One of Israel: “For your sake, I have sent to Babylon, and I will bring all of them down as fugitives, even the Chaldeans, in the ships of their rejoicing.", "bsb": "Thus says the LORD your Redeemer, the Holy One of Israel: “For your sake, I will send to Babylon and bring them all as fugitives, even the Chaldeans, in the ships in which they rejoice.", "asv": "Thus saith Jehovah, your Redeemer, the Holy One of Israel: For your sake I have sent to Babylon, and I will bring down all of them as fugitives, even the Chaldeans, in the ships of their rejoicing.", "ylt": "Thus said Jehovah, your Redeemer, The Holy One of Israel: `For your sake I have sent to Babylon, And caused bars to descend--all of them, And the Chaldeans, whose song is in the ships.", "dra": "Thus saith the Lord your redeemer, the Holy One of Israel: For your sake I sent to Babylon, and have brought down all their bars, and the Chaldeans glorying in their ships.", "bbe": "The Lord, who has taken up your cause, the Holy One of Israel, says, Because of you I have sent to Babylon, and made all their seers come south, and the Chaldaeans whose cry is in the ships.", "geneva": "Thus sayeth the Lord your redeemer, the holy one of Israel, For your sake I haue sent to Babel, and brought it downe: they are all fugitiues, and the Chaldeans crie in the shippes.", "wycliffe": "The Lord, youre ayenbiere, the hooli of Israel, seith these thingis, For you Y sente out in to Babiloyne, and Y drow doun alle barris, and Caldeis hauynge glorie in her schippis.", "rotherham": "Thus saith Yahweh, Your Redeemer, The Holy One of Israel,—For your sakes, have I sent into Babylon, And will bring down as fugitives, all of them,—Even the Chaldeans, in the ships which cause them loud outcry.", "darby": "Thus saith Jehovah, your Redeemer, the Holy One of Israel: For your sake I have sent to Babylon, and have brought all of them down as fugitives, even the Chaldeans, whose cry is in the ships.", "twenty": "", "jps": "Thus saith HaShem, your Redeemer, The Holy One of Israel: For your sake I have sent to Babylon, and I will bring down all of them as fugitives, even the Chaldeans, in the ships of their shouting.", "acv": "Thus says Jehovah, your Redeemer, the Holy One of Israel: For your sake I have sent to Babylon, and I will bring down all of them as fugitives, even the Chaldeans, in the ships of their rejoicing.", "anderson": "", "haweis": "", "noyes": "Thus saith Jehovah, Your redeemer, the Holy One of Israel; For your sakes have I sent to Babylon, And caused all her fugitives, And the Chaldeans, to descend to the ships of their delight.", "webster": "Thus saith the LORD, your Redeemer, the Holy One of Israel; For your sake I have sent to Babylon, and have brought down all their nobles, and the Chaldeans, whose cry [is] in the ships.", "vulgate": "haec dicit Dominus redemptor vester Sanctus Israhel propter vos emisi Babylonem et detraxi vectes universos et Chaldeos in navibus suis gloriantes;", "brenton": "Thus saith the Lord God that redeems you, the Holy One of Israel; for your sakes I will send to Babylon, and I will stir up all that flee, and the Chaldeans shall be bound in ships."}}, {"v": 15, "ref": "43:15", "o": "אֲנִ֥י יְהוָ֖ה קְדֽוֹשְׁ/כֶ֑ם בּוֹרֵ֥א יִשְׂרָאֵ֖ל מַלְכְּ/כֶֽם", "en": {"kjv": "I am the Lord, your Holy One, the creator of Israel, your King.", "web": "I am Yahweh, your Holy One, the Creator of Israel, your King.”", "bsb": "I am the LORD, your Holy One, the Creator of Israel, and your King.”", "asv": "I am Jehovah, your Holy One, the Creator of Israel, your King.", "ylt": "I am Jehovah, your Holy One, Creator of Israel, your King.'", "dra": "I am the Lord your Holy One, the Creator of Israel, your King.", "bbe": "I am the Lord, your Holy One, the Maker of Israel, your King.", "geneva": "I am the Lord your holy one, the creator of Israel, your King.", "wycliffe": "Y am the Lord, youre hooli, youre king, makynge Israel of nouyt.", "rotherham": "I—Yahweh, am Your Holy One,—The Creator of Israel, Your King.", "darby": "I [am] Jehovah, your Holy One, the Creator of Israel, your King.", "twenty": "", "jps": "I am HaShem, your Holy One, the Creator of Israel, your King.", "acv": "I am Jehovah, your Holy One, the Creator of Israel, your King.", "anderson": "", "haweis": "", "noyes": "I, Jehovah, am your Holy One, The creator of Israel, your king.", "webster": "I [am] the LORD, your Holy One, the Creator of Israel, your King.", "vulgate": "ego Dominus Sanctus vester creans Israhel Rex vester;", "brenton": "I am the Lord God, your Holy One, who have appointed for Israel your king."}}, {"v": 16, "ref": "43:16", "o": "כֹּ֚ה אָמַ֣ר יְהוָ֔ה הַ/נּוֹתֵ֥ן בַּ/יָּ֖ם דָּ֑רֶךְ וּ/בְ/מַ֥יִם עַזִּ֖ים נְתִיבָֽה", "en": {"kjv": "Thus saith the Lord, which maketh a way in the sea, and a path in the mighty waters;", "web": "Thus says Yahweh, who makes a way in the sea, and a path in the mighty waters;", "bsb": "Thus says the LORD, who makes a way in the sea and a path through the surging waters,", "asv": "Thus saith Jehovah, who maketh a way in the sea, and a path in the mighty waters;", "ylt": "Thus said Jehovah, Who is giving in the sea a way, And in the strong waters a path.", "dra": "Thus saith the Lord, who made a way in the sea, and a path in the mighty waters.", "bbe": "This is the word of the Lord, who makes a way in the sea, and a road through the deep waters;", "geneva": "Thus sayeth the Lord which maketh a way in the Sea, and a path in the mighty waters.", "wycliffe": "The Lord seith these thingis, that yaf weie in the see, and a path in rennynge watris;", "rotherham": "Thus, saith Yahweh,—Who setteth in the sea, a way,—And in the mighty waters, a path;", "darby": "Thus saith Jehovah, who maketh a way in the sea, and a path in the mighty waters,", "twenty": "", "jps": "Thus saith HaShem, who maketh a way in the sea, and a path in the mighty waters;", "acv": "Thus says Jehovah, who makes a way in the sea, and a path in the mighty waters,", "anderson": "", "haweis": "", "noyes": "Thus saith Jehovah,—He that made a way in the sea, And a path in the mighty waters,", "webster": "Thus saith the LORD, who maketh a way in the sea, and a path in the mighty waters;", "vulgate": "haec dicit Dominus qui dedit in mari viam et in aquis torrentibus semitam;", "brenton": "Thus saith the Lord, who makes a way in the sea, and a path in the mighty water;"}}, {"v": 17, "ref": "43:17", "o": "הַ/מּוֹצִ֥יא רֶֽכֶב וָ/ס֖וּס חַ֣יִל וְ/עִזּ֑וּז יַחְדָּ֤ו יִשְׁכְּבוּ֙ בַּל יָק֔וּמוּ דָּעֲכ֖וּ כַּ/פִּשְׁתָּ֥ה כָבֽוּ", "en": {"kjv": "Which bringeth forth the chariot and horse, the army and the power; they shall lie down together, they shall not rise: they are extinct, they are quenched as tow.", "web": "who brings out the chariot and horse, the army and the mighty man (they lie down together, they shall not rise; they are extinct, they are quenched like a wick):", "bsb": "who brings out the chariots and horses, the armies and warriors together, to lie down, never to rise again; to be extinguished, snuffed out like a wick:", "asv": "who bringeth forth the chariot and horse, the army and the mighty man (they lie down together, they shall not rise; they are extinct, they are quenched as a wick):", "ylt": "Who is bringing forth chariot and horse, A force, even a strong one: `Together they lie down--they rise not, They have been extinguished, As flax they have been quenched.'", "dra": "Who brought forth the chariot and the horse, the army and the strong: they lay down to sleep together, and they shall not rise again: they are broken as flax, and are extinct.", "bbe": "Who sends out the war-carriages and the horses, the army with all its force; they have come down, they will not get up again; like a feebly burning light they are put out.", "geneva": "When hee bringeth out the charet and horse, the armie and the power lie together, and shall not rise: they are extinct, and quenched as towe.", "wycliffe": "which ledde out a carte, and hors, a cumpany, and strong man; thei slepten togidere, nether thei schulen rise ayen; thei ben al tobrokun as flex, and ben quenchid.", "rotherham": "Who bringeth forth Chariot and horse, Force and strength, Together, shall they lie down They shall not arise, They are extinguished Like a wick, are they quenched!", "darby": "who bringeth forth chariot and horse, army and power — they lie down together, they shall not rise; they are extinct, they are quenched as tow:", "twenty": "", "jps": "Who bringeth forth the chariot and horse, the army and the power--they lie down together, they shall not rise, they are extinct, they are quenched as a wick:", "acv": "who brings forth the chariot and horse, the army and the mighty man (they lie down together; they shall not rise; they are extinct; they are quenched as a wick):", "anderson": "", "haweis": "", "noyes": "That caused the chariot and the horse, the army and the forces, to march forth; There they lay down together; they rose no more; They were extinguished; they were quenched like a torch; —", "webster": "Who bringeth forth the chariot and horse, the army and the power; they shall lie down together, they shall not rise: they are extinct, they are quenched as tow.", "vulgate": "qui eduxit quadrigam et equum agmen et robustum simul obdormierunt nec resurgent contriti sunt quasi linum et extincti sunt;", "brenton": "who brought forth chariots and horse, and a mighty multitude: but they have lain down, and shall not rise: they are extinct, as quenched flax."}}, {"v": 18, "ref": "43:18", "o": "אַֽל תִּזְכְּר֖וּ רִֽאשֹׁנ֑וֹת וְ/קַדְמֹנִיּ֖וֹת אַל תִּתְבֹּנָֽנוּ", "en": {"kjv": "Remember ye not the former things, neither consider the things of old.", "web": "“Don’t remember the former things, and don’t consider the things of old.", "bsb": "“Do not call to mind the former things; pay no attention to the things of old.", "asv": "Remember ye not the former things, neither consider the things of old.", "ylt": "Remember not former things, And ancient things consider not.", "dra": "Remember not former things, and look not on things of old.", "bbe": "Give no thought to the things which are past; let the early times go out of your minds.", "geneva": "Remember yee not the former things, neither regard the things of olde.", "wycliffe": "Thenke ye not on the formere thingis, and biholde ye not olde thingis.", "rotherham": "Do not keep in mind former things,—And things of old, do not consider:", "darby": "— Remember not the former things, neither consider the ancient things:", "twenty": "", "jps": "Remember ye not the former things, neither consider the things of old.", "acv": "Do not remember ye the former things, nor consider the things of old.", "anderson": "", "haweis": "", "noyes": "Remember not the former things; The things of old regard no more!", "webster": "Remember ye not the former things, neither consider the things of old.", "vulgate": "ne memineritis priorum et antiqua ne intueamini;", "brenton": "Remember ye not the former things, and consider not the ancient things."}}, {"v": 19, "ref": "43:19", "o": "הִנְ/נִ֨י עֹשֶׂ֤ה חֲדָשָׁה֙ עַתָּ֣ה תִצְמָ֔ח הֲ/ל֖וֹא תֵֽדָע֑וּ/הָ אַ֣ף אָשִׂ֤ים בַּ/מִּדְבָּר֙ דֶּ֔רֶךְ בִּֽ/ישִׁמ֖וֹן נְהָרֽוֹת", "en": {"kjv": "Behold, I will do a new thing; now it shall spring forth; shall ye not know it? I will even make a way in the wilderness, and rivers in the desert.", "web": "Behold, I will do a new thing. It springs out now. Don’t you know it? I will even make a way in the wilderness, and rivers in the desert.", "bsb": "Behold, I am about to do something new; even now it is coming. Do you not see it? Indeed, I will make a way in the wilderness and streams in the desert.", "asv": "Behold, I will do a new thing; now shall it spring forth; shall ye not know it? I will even make a way in the wilderness, and rivers in the desert.", "ylt": "Lo, I am doing a new thing, now it springeth up, Do ye not know it? Yea, I put in a wilderness a way, In a desolate place--floods.", "dra": "Behold I do new things, and now they shall spring forth, verily you shall know them: I will make a way in the wilderness, and rivers in the desert.", "bbe": "See, I am doing a new thing; now it is starting; will you not take note of it? I will even make a way in the waste land, and rivers in the dry country.", "geneva": "Behold, I do a new thing: now shall it come foorth: shall you not knowe it? I wil euen make a way in the desert, and floods in the wildernesse.", "wycliffe": "Lo! Y make newe thingis, and now tho schulen bigynne to be maad; sotheli ye schulen know tho. Y schal sette weie in desert, and floodis in a lond without weie.", "rotherham": "Behold me! doing a new thing, Now, shall it spring forth, Will ye not take note thereof? Surely I will set In the desert, a way, In a desolate land, rivers:", "darby": "behold, I do a new thing; now it shall spring forth: shall ye not know it? I will even make a way in the wilderness, rivers in the waste.", "twenty": "", "jps": "Behold, I will do a new thing; now shall it spring forth; shall ye not know it? I will even make a way in the wilderness, and rivers in the desert.", "acv": "Behold, I will do a new thing. Now it shall spring forth. Shall ye not know it? I will even make a way in the wilderness, and rivers in the desert.", "anderson": "", "haweis": "", "noyes": "Behold, I do a new thing; Now shall it spring forth; yea, ye shall see it. Behold, I make a way in the wilderness, And streams in the desert;", "webster": "Behold, I will do a new thing; now it shall spring forth; shall ye not know it? I will even make a way in the wilderness, [and] rivers in the desert.", "vulgate": "ecce ego facio nova et nunc orientur utique cognoscetis ea ponam in deserto viam et in invio flumina;", "brenton": "Behold, I will do new things, which shall presently spring forth, and ye shall know them: and I will make a way in the wilderness, and rivers in the dry land."}}, {"v": 20, "ref": "43:20", "o": "תְּכַבְּדֵ֨/נִי֙ חַיַּ֣ת הַ/שָּׂדֶ֔ה תַּנִּ֖ים וּ/בְנ֣וֹת יַֽעֲנָ֑ה כִּֽי נָתַ֨תִּי בַ/מִּדְבָּ֜ר מַ֗יִם נְהָרוֹת֙ בִּֽ/ישִׁימֹ֔ן לְ/הַשְׁק֖וֹת עַמִּ֥/י בְחִירִֽ/י", "en": {"kjv": "The beast of the field shall honour me, the dragons and the owls: because I give waters in the wilderness, and rivers in the desert, to give drink to my people, my chosen.", "web": "The animals of the field shall honor me, the jackals and the ostriches; because I give water in the wilderness and rivers in the desert, to give drink to my people, my chosen,", "bsb": "The beasts of the field will honor Me, the jackals and the ostriches, because I provide water in the wilderness and rivers in the desert, to give drink to My chosen people.", "asv": "The beasts of the field shall honor me, the jackals and the ostriches; because I give waters in the wilderness, and rivers in the desert, to give drink to my people, my chosen,", "ylt": "Honour me doth the beast of the field, Dragons and daughters of an ostrich, For I have given in a wilderness waters, Floods in a desolate place, To give drink to My people--My chosen.", "dra": "The beast of the field shall glorify me, the dragons and the ostriches: because I have given waters in the wilderness, rivers in the desert, to give drink to my people, to my chosen.", "bbe": "The beasts of the field will give me honour, the jackals and the ostriches: because I send out waters in the waste land, and rivers in the dry country, to give drink to the people whom I have taken for myself:", "geneva": "The wilde beastes shall honour mee, the dragons and the ostriches, because I gaue water in the desert, and floods in the wildernesse to giue drinke to my people, euen to mine elect.", "wycliffe": "And a beeste of the feelde schal glorifie me, dragouns and ostrigis schulen glorifie me; for Y yaf watris in desert, and floodis in the lond without weie, that Y schulde yyue drynk to my puple, to my chosun puple.", "rotherham": "The wild beast of the field shall honour me, Jackals, and ostriches, Because I have given—In the desert, waters, Rivers in, desolate land, To give drink unto my people, my chosen:", "darby": "The beast of the field shall glorify me, the jackals and the ostriches; for I will give waters in the wilderness, rivers in the waste, to give drink to my people, my chosen.", "twenty": "", "jps": "The beasts of the field shall honour Me, the jackals and the ostriches; because I give waters in the wilderness, and rivers in the desert, to give drink to My people, Mine elect;", "acv": "The beasts of the field shall honor me, the jackals and the ostriches, because I give waters in the wilderness, and rivers in the desert, to give drink to my people, my chosen,", "anderson": "", "haweis": "", "noyes": "The beasts of the forest shall honor me, The jackals and the ostriches; For I make rivers in the wilderness And streams in the desert, To give drink to my people, my chosen.", "webster": "The beast of the field shall honor me, the dragons and the owls: because I give waters in the wilderness, [and] rivers in the desert, to give drink to my people, my chosen.", "vulgate": "glorificabit me bestia agri dracones et strutiones quia dedi in deserto aquas flumina in invio ut darem potum populo meo electo meo;", "brenton": "the beasts of the field shall bless me, the owls and young ostriches; for I have given water in the wilderness, and rivers in the dry land, to give drink to my chosen race,"}}, {"v": 21, "ref": "43:21", "o": "עַם זוּ֙ יָצַ֣רְתִּי לִ֔/י תְּהִלָּתִ֖/י יְסַפֵּֽרוּ", "en": {"kjv": "This people have I formed for myself; they shall shew forth my praise.", "web": "the people which I formed for myself, that they might declare my praise.", "bsb": "The people I formed for Myself will declare My praise.", "asv": "the people which I formed for myself, that they might set forth my praise.", "ylt": "This people I have formed for Myself, My praise they recount.", "dra": "This people have I formed for myself, they shall shew forth my praise.", "bbe": "Even the people whom I made to be the witnesses of my praise.", "geneva": "This people haue I formed for my selfe: they shall shewe foorth my praise.", "wycliffe": "Y fourmyde this puple to me, it schal telle my preysyng.", "rotherham": "A people which I have fashioned for myself, My praise, shall they record.", "darby": "This people have I formed for myself: they shall shew forth my praise.", "twenty": "", "jps": "The people which I formed for Myself, that they might tell of My praise.", "acv": "the people whom I formed for myself, that they might set forth my praise.", "anderson": "", "haweis": "", "noyes": "This people, which I have formed for myself Shall make known my praise.", "webster": "This people have I formed for myself; they shall show forth my praise.", "vulgate": "populum istum formavi mihi laudem meam narrabit;", "brenton": "my people whom I have preserved to tell forth my praises."}}, {"v": 22, "ref": "43:22", "o": "וְ/לֹא אֹתִ֥/י קָרָ֖אתָ יַֽעֲקֹ֑ב כִּֽי יָגַ֥עְתָּ בִּ֖/י יִשְׂרָאֵֽל", "en": {"kjv": "But thou hast not called upon me, O Jacob; but thou hast been weary of me, O Israel.", "web": "Yet you have not called on me, Jacob; but you have been weary of me, Israel.", "bsb": "But you have not called on Me, O Jacob, because you have grown weary of Me, O Israel.", "asv": "Yet thou hast not called upon me, O Jacob; but thou hast been weary of me, O Israel.", "ylt": "And Me thou hast not called, O Jacob, For thou hast been wearied of me, O Israel,", "dra": "But thou hast not called upon me, O Jacob, neither hast thou laboured about me, O Israel.", "bbe": "But you have made no prayer to me, O Jacob: and you have given no thought to me, O Israel.", "geneva": "And thou hast not called vpon mee, O Iaakob, but thou hast wearied me, O Israel.", "wycliffe": "Jacob, thou clepidist not me to help; and thou, Israel, trauelidist not for me.", "rotherham": "Yet not upon me, hast thou called, O Jacob,—For thou hast been wearied of me O Israel:", "darby": "— But thou hast not called upon me, Jacob; for thou hast been weary of me, O Israel:", "twenty": "", "jps": "Yet thou hast not called upon Me, O Jacob, neither hast thou wearied thyself about Me, O Israel.", "acv": "Yet thou have not called upon me, O Jacob, but thou have been weary of me, O Israel.", "anderson": "", "haweis": "", "noyes": "Yet thou hast not called upon me, O Jacob, So as to have wearied thyself for me, O Israel!", "webster": "But thou hast not called upon me, O Jacob; but thou hast been weary of me, O Israel.", "vulgate": "non me invocasti Iacob nec laborasti in me Israhel;", "brenton": "I have not now called thee, O Jacob; neither have I made thee weary, O Israel."}}, {"v": 23, "ref": "43:23", "o": "לֹֽא הֵבֵ֤יאתָ לִּ/י֙ שֵׂ֣ה עֹלֹתֶ֔י/ךָ וּ/זְבָחֶ֖י/ךָ לֹ֣א כִבַּדְתָּ֑/נִי לֹ֤א הֶעֱבַדְתִּ֨י/ךָ֙ בְּ/מִנְחָ֔ה וְ/לֹ֥א הוֹגַעְתִּ֖י/ךָ בִּ/לְבוֹנָֽה", "en": {"kjv": "Thou hast not brought me the small cattle of thy burnt offerings; neither hast thou honoured me with thy sacrifices. I have not caused thee to serve with an offering, nor wearied thee with incense.", "web": "You have not brought me of your sheep for burnt offerings; neither have you honored me with your sacrifices. I have not burdened you with offerings, nor wearied you with frankincense.", "bsb": "You have not brought Me sheep for burnt offerings, nor honored Me with your sacrifices. I have not burdened you with offerings, nor wearied you with frankincense.", "asv": "Thou hast not brought me of thy sheep for burnt-offerings; neither hast thou honored me with thy sacrifices. I have not burdened thee with offerings, nor wearied thee with frankincense.", "ylt": "Thou hast not brought in to Me, The lamb of thy burnt-offerings, And with thy sacrifices thou hast not honoured Me, I have not caused thee to serve with a present, Nor wearied thee with frankincense.", "dra": "Thou hast not offered me the ram of thy holocaust, nor hast thou glorified me with thy victims: I have not caused thee to serve with oblations, nor wearied thee with incense.", "bbe": "You have not made me burned offerings of sheep, or given me honour with your offerings of beasts; I did not make you servants to give me an offering, and I did not make you tired with requests for perfumes.", "geneva": "Thou hast not brought me the sheepe of thy burnt offrings, neither hast thou honoured me with thy sacrifices. I haue not caused thee to serue with an offring, nor wearied thee with incense.", "wycliffe": "Thou offridist not to me the ram of thi brent sacrifice, and thou glorifiedist not me with thi slayn sacrifices. Y made not thee to serue in offryng, nethir Y yaf to thee trauel in encense.", "rotherham": "Thou hast not brought in to me small cattle as thine ascending-offerings, Nor, with thy sacrifices, hast thou honoured me,—I have not oppressed thee with meal-offerings, Nor have I wearied thee with frankincense;", "darby": "thou hast not brought me the small cattle of thy burnt-offerings, neither hast thou glorified me with thy sacrifices. I have not caused thee to toil with an oblation, nor wearied thee with incense.", "twenty": "", "jps": "Thou hast not brought Me the small cattle of thy burnt-offerings; neither hast thou honoured Me with thy sacrifices. I have not burdened thee with a meal-offering, nor wearied thee with frankincense.", "acv": "Thou have not brought me from thy sheep for burnt offerings, nor have thou honored me with thy sacrifices. I have not burdened thee with offerings, nor wearied thee with frankincense.", "anderson": "", "haweis": "", "noyes": "Thou hast not brought me thy lambs for a burnt-offering, Nor honored me with thy sacrifices; I have not burdened thee with oblations, Nor wearied thee with incense;", "webster": "Thou hast not brought me the small cattle of thy burnt-offerings; neither hast thou honored me with thy sacrifices. I have not caused thee to serve with an offering, nor wearied thee with incense.", "vulgate": "non obtulisti mihi arietem holocausti tui et victimis tuis non glorificasti me non te servire feci in oblatione nec laborem tibi praebui in ture;", "brenton": "Thou hast not brought me the sheep of thy whole-burnt-offering; neither hast thou glorified me with thy sacrifices. I have not caused thee to serve with sacrifices, neither have I wearied thee with frankincense."}}, {"v": 24, "ref": "43:24", "o": "לֹא קָנִ֨יתָ לִּ֤/י בַ/כֶּ֨סֶף֙ קָנֶ֔ה וְ/חֵ֥לֶב זְבָחֶ֖י/ךָ לֹ֣א הִרְוִיתָ֑/נִי אַ֗ךְ הֶעֱבַדְתַּ֨/נִי֙ בְּ/חַטֹּאותֶ֔י/ךָ הוֹגַעְתַּ֖/נִי בַּ/עֲוֺנֹתֶֽי/ךָ", "en": {"kjv": "Thou hast bought me no sweet cane with money, neither hast thou filled me with the fat of thy sacrifices: but thou hast made me to serve with thy sins, thou hast wearied me with thine iniquities.", "web": "You have bought me no sweet cane with money, nor have you filled me with the fat of your sacrifices; but you have burdened me with your sins. You have wearied me with your iniquities.", "bsb": "You have not bought Me sweet cane with your silver, nor satisfied Me with the fat of your sacrifices. But you have burdened Me with your sins; you have wearied Me with your iniquities.", "asv": "Thou hast bought me no sweet cane with money, neither hast thou filled me with the fat of thy sacrifices; but thou hast burdened me with thy sins, thou hast wearied me with thine iniquities.", "ylt": "Thou hast not bought for Me with money sweet cane, And with the fat of thy sacrifices hast not filled Me, Only--thou hast caused Me to serve with thy sins, Thou hast wearied Me with thine iniquities.", "dra": "Thou hast bought me no sweet cane with money, neither hast thou filled me with the fat of thy victims. But thou hast made me to serve with thy sins, thou hast wearied me with thy iniquities.", "bbe": "You have not got me sweet-smelling plants with your money, or given me pleasure with the fat of your offerings: but you have made me a servant to your sins, and you have made me tired with your evil doings.", "geneva": "Thou boughtest mee no sweete sauour with money, neither hast thou made mee drunke with the fatte of thy sacrifices, but thou hast made mee to serue with thy sinnes, and wearied mee with thine iniquities.", "wycliffe": "Thou bouytist not to me swete smellynge spicerie for siluer, and thou fillidist not me with fatnesse of thi slayn sacrifices; netheles thou madist me to serue in thi synnes, thou yauest trauel to me in thi wickidnessis.", "rotherham": "Thou hast not bought for me with silver, fragrant calamus, Nor with the fat of thy sacrifices, hast thou sated me,—Thou hast done nothing but oppress me with thy sins, Thou hast wearied me with thine iniquities.", "darby": "Thou hast bought me no sweet cane with money, neither hast thou filled me with the fat of thy sacrifices; but thou hast made me to toil with thy sins, thou hast wearied me with thine iniquities.", "twenty": "", "jps": "Thou hast bought Me no sweet cane with money, neither hast thou satisfied Me with the fat of thy sacrifices; but thou hast burdened Me with thy sins, thou hast wearied Me with thine iniquities.", "acv": "Thou have bought me no sweet cane with money, nor have thou filled me with the fat of thy sacrifices. But thou have burdened me with thy sins. Thou have wearied me with thine iniquities.", "anderson": "", "haweis": "", "noyes": "Thou hast bought me no sweet-smelling reed with silver, Neither hast thou satisfied me with the fat of thy sacrifices; With thy sins hast thou burdened me, And wearied me with thine iniquities.", "webster": "Thou hast bought me no sweet cane with money, neither hast thou filled me with the fat of thy sacrifices: but thou hast made me to serve with thy sins, thou hast wearied me with thy iniquities.", "vulgate": "non emisti mihi argento calamum et adipe victimarum tuarum non inebriasti me verumtamen servire me fecisti in peccatis tuis praebuisti mihi laborem in iniquitatibus tuis;", "brenton": "Neither hast thou purchased for me victims for silver, neither have I desired the fat of thy sacrifices: but thou didst stand before me in thy sins, and in thine iniquities."}}, {"v": 25, "ref": "43:25", "o": "אָנֹכִ֨י אָנֹכִ֥י ה֛וּא מֹחֶ֥ה פְשָׁעֶ֖י/ךָ לְמַעֲנִ֑/י וְ/חַטֹּאתֶ֖י/ךָ לֹ֥א אֶזְכֹּֽר", "en": {"kjv": "I, even I, am he that blotteth out thy transgressions for mine own sake, and will not remember thy sins.", "web": "I, even I, am he who blots out your transgressions for my own sake; and I will not remember your sins.", "bsb": "I, yes I, am He who blots out your transgressions for My own sake and remembers your sins no more.", "asv": "I, even I, am he that blotteth out thy transgressions for mine own sake; and I will not remember thy sins.", "ylt": "I--I am He who is blotting out Thy transgressions for Mine own sake, And thy sins I do not remember.", "dra": "I am, I am he that blot out thy iniquities for my own sake, and I will not remember thy sins.", "bbe": "I, even I, am he who takes away your sins; and I will no longer keep your evil doings in mind.", "geneva": "I, euen I am he that putteth away thine iniquities for mine owne sake, and will not remember thy sinnes.", "wycliffe": "Y am, Y my silf am, that do awei thi wickidnessis for me, and Y schal not haue mynde on thy synnes.", "rotherham": "I—I, am he that is ready, To wipe out thy transgressions for mine own sake,—And, thy sins, not remember.", "darby": "— I, I [am] He that blotteth out thy transgressions for mine own sake, and I will not remember thy sins.", "twenty": "", "jps": "I, even I, am He that blotteth out thy transgressions for Mine own sake; and thy sins I will not remember.", "acv": "I, even I, am he who blots out thy transgressions for my own sake, and I will not remember thy sins.", "anderson": "", "haweis": "", "noyes": "I, I myself, blot out thy transgressions for my own sake, And will not remember thy sins.", "webster": "I, [even] I, [am] he that blotteth out thy transgressions for my own sake, and will not remember thy sins.", "vulgate": "ego sum ego sum ipse qui deleo iniquitates tuas propter me et peccatorum tuorum non recordabor;", "brenton": "I, even I, am he that blots out thy transgressions for mine own sake, and thy sins; and I will not remember them."}}, {"v": 26, "ref": "43:26", "o": "הַזְכִּירֵ֕/נִי נִשָּׁפְטָ֖ה יָ֑חַד סַפֵּ֥ר אַתָּ֖ה לְמַ֥עַן תִּצְדָּֽק", "en": {"kjv": "Put me in remembrance: let us plead together: declare thou, that thou mayest be justified.", "web": "Put me in remembrance. Let us plead together. Declare your case, that you may be justified.", "bsb": "Remind Me, let us argue the matter together. State your case, so that you may be vindicated.", "asv": "Put me in remembrance; let us plead together: set thou forth thy cause, that thou mayest be justified.", "ylt": "Cause me to remember--we are judged together, Declare thou that thou mayest be justified.", "dra": "Put me in remembrance, and let us plead together: tell if thou hast any thing to justify thyself.", "bbe": "Put me in mind of this; let us take up the cause between us: put forward your cause, so that you may be seen to be in the right.", "geneva": "Put me in remembrance: let vs be iudged together: count thou that thou maist be iustified.", "wycliffe": "Brynge me ayen in to mynde, and be we demyd togidere; telle thou, if thou hast ony thing, that thou be iustified.", "rotherham": "Put me in mind, Let us enter into judgment at once,—Recount, thou, that thou mayest be justified:", "darby": "Put me in remembrance, let us plead together; rehearse thine own [cause], that thou mayest be justified.", "twenty": "", "jps": "Put Me in remembrance, let us plead together; declare thou, that thou mayest be justified.", "acv": "Put me in remembrance. Let us plead together. Set thou forth thy case that thou may be justified.", "anderson": "", "haweis": "", "noyes": "Put me in remembrance; let us plead together; Speak that thou mayst justify thyself.", "webster": "Put me in remembrance: let us plead together: declare thou, that thou mayest be justified.", "vulgate": "reduc me in memoriam et iudicemur simul narra si quid habes ut iustificeris;", "brenton": "But do thou remember, and let us plead together: do thou first confess thy transgressions, that thou mayest be justified."}}, {"v": 27, "ref": "43:27", "o": "אָבִ֥י/ךָ הָ/רִאשׁ֖וֹן חָטָ֑א וּ/מְלִיצֶ֖י/ךָ פָּ֥שְׁעוּ בִֽ/י", "en": {"kjv": "Thy first father hath sinned, and thy teachers have transgressed against me.", "web": "Your first father sinned, and your teachers have transgressed against me.", "bsb": "Your first father sinned, and your spokesmen rebelled against Me.", "asv": "Thy first father sinned, and thy teachers have transgressed against me.", "ylt": "Thy first father sinned, And thine interpreters transgressed against me,", "dra": "Thy first father sinned, and thy teachers have transgressed against me.", "bbe": "Your first father was a sinner, and your guides have gone against my word.", "geneva": "Thy first father hath sinned, and thy teachers haue transgressed against me.", "wycliffe": "Thi firste fadir synnede, and thin interpretours trespassiden ayens me.", "rotherham": "Thy chief father, hath sinned, And thine interpreters, have transgressed against me;", "darby": "Thy first father hath sinned, and thy mediators have rebelled against me.", "twenty": "", "jps": "Thy first father sinned, and thine intercessors have transgressed against Me.", "acv": "Thy first father sinned, and thy teachers have transgressed against me.", "anderson": "", "haweis": "", "noyes": "Thy forefathers sinned, And thy teachers were rebellious against me;", "webster": "Thy first father hath sinned, and thy teachers have transgressed against me.", "vulgate": "pater tuus primus peccavit et interpretes tui praevaricati sunt in me;", "brenton": "Your fathers first, and your princes have transgressed against me."}}, {"v": 28, "ref": "43:28", "o": "וַ/אֲחַלֵּ֖ל שָׂ֣רֵי קֹ֑דֶשׁ וְ/אֶתְּנָ֤ה לַ/חֵ֨רֶם֙ יַעֲקֹ֔ב וְ/יִשְׂרָאֵ֖ל לְ/גִדּוּפִֽים", "en": {"kjv": "Therefore I have profaned the princes of the sanctuary, and have given Jacob to the curse, and Israel to reproaches.", "web": "Therefore I will profane the princes of the sanctuary; and I will make Jacob a curse, and Israel an insult.”", "bsb": "So I will disgrace the princes of your sanctuary, and I will devote Jacob to destruction and Israel to reproach.”", "asv": "Therefore I will profane the princes of the sanctuary; and I will make Jacob a curse, and Israel a reviling.", "ylt": "And I pollute princes of the sanctuary, And I give Jacob to destruction, and Israel to revilings!", "dra": "And I have profaned the holy princes, I have given Jacob to slaughter, and Israel to reproach.", "bbe": "Your chiefs have made my holy place unclean, so I have made Jacob a curse, and Israel a thing of shame.", "geneva": "Therefore I haue prophaned the rulers of the Sanctuarie, and haue made Iaakob a curse, and Israel a reproche.", "wycliffe": "And Y made foul hooli princes, and Y yaf Jacob to deth, and Israel in to blasfemye.", "rotherham": "So then I must needs profane the rulers of the holy place,—And deliver Jacob to be devoted to destruction, and Israel, unto reviling!", "darby": "And I have profaned the princes of the sanctuary, and have given Jacob to the ban, and Israel to reproaches.", "twenty": "", "jps": "Therefore I have profaned the princes of the sanctuary, and I have given Jacob to condemnation, and Israel to reviling.", "acv": "Therefore I will profane the rulers of the sanctuary, and I will make Jacob a curse, and Israel a reviling.", "anderson": "", "haweis": "", "noyes": "Therefore have I profaned the princes of the sanctuary, And given up Jacob to a curse, And Israel to reproach.", "webster": "Therefore I have profaned the princes of the sanctuary, and have given Jacob to the curse, and Israel to reproaches.", "vulgate": "et contaminavi principes sanctos dedi ad internicionem Iacob et Israhel in blasphemiam;", "brenton": "And the princes have defiled my sanctuaries: so I gave Jacob to enemies to destroy, and Israel to reproach."}}]}, {"c": 44, "verses": [{"v": 1, "ref": "44:1", "o": "וְ/עַתָּ֥ה שְׁמַ֖ע יַעֲקֹ֣ב עַבְדִּ֑/י וְ/יִשְׂרָאֵ֖ל בָּחַ֥רְתִּי בֽ/וֹ", "en": {"kjv": "Yet now hear, O Jacob my servant; and Israel, whom I have chosen:", "web": "Yet listen now, Jacob my servant, and Israel, whom I have chosen.", "bsb": "But now listen, O Jacob My servant, Israel, whom I have chosen.", "asv": "Yet now hear, O Jacob my servant, and Israel, who I have chosen:", "ylt": "And now, hear, O Jacob, My servant, And Israel, whom I have fixed on:", "dra": "And now hear, O Jacob, my servant, and Israel whom I have chosen.", "bbe": "And now, give ear, O Jacob my servant, and Israel whom I have taken for myself:", "geneva": "Yet nowe heare, O Iaakob my seruant, and Israel, whom I haue chosen.", "wycliffe": "And now, Jacob, my seruaunt, here thou, and Israel, whom I chees.", "rotherham": "Now, then—hear, O Jacob, my Servant,—and Israel whom I have chosen:", "darby": "And now hear, Jacob, my servant, and Israel, whom I have chosen:", "twenty": "", "jps": "Yet now hear, O Jacob My servant, and Israel, whom I have chosen;", "acv": "Yet now hear, O Jacob my servant, and Israel, whom I have chosen.", "anderson": "", "haweis": "", "noyes": "Yet now hear, O Jacob, my servant, And Israel, whom I have chosen;", "webster": "Yet now hear, O Jacob my servant; and Israel, whom I have chosen:", "vulgate": "et nunc audi Iacob serve meus et Israhel quem elegi;", "brenton": "But now hear, Jacob my servant; and Israel, whom I have chosen."}}, {"v": 2, "ref": "44:2", "o": "כֹּה אָמַ֨ר יְהוָ֥ה עֹשֶׂ֛/ךָ וְ/יֹצֶרְ/ךָ֥ מִ/בֶּ֖טֶן יַעְזְרֶ֑/ךָּ אַל תִּירָא֙ עַבְדִּ֣/י יַֽעֲקֹ֔ב וִ/ישֻׁר֖וּן בָּחַ֥רְתִּי בֽ/וֹ", "en": {"kjv": "Thus saith the Lord that made thee, and formed thee from the womb, which will help thee; Fear not, O Jacob, my servant; and thou, Jesurun, whom I have chosen.", "web": "This is what Yahweh who made you, and formed you from the womb, who will help you says: “Don’t be afraid, Jacob my servant; and you, Jeshurun, whom I have chosen.", "bsb": "This is the word of the LORD, your Maker, who formed you from the womb and who will help you: “Do not be afraid, O Jacob My servant, Jeshurun, whom I have chosen.", "asv": "Thus saith Jehovah that made thee, and formed thee from the womb, who will help thee: Fear not, O Jacob my servant; and thou, Jeshurun, whom I have chosen.", "ylt": "Thus said Jehovah, thy Maker, and thy Former, From the womb He doth help thee; Fear not, my servant Jacob, And Jeshurun, whom I have fixed on.", "dra": "Thus saith the Lord that made and formed thee, thy helper from the womb: Fear not, O my servant Jacob, and thou most righteous whom I have chosen.", "bbe": "The Lord who made you, forming you in your mother's body, the Lord, your helper, says, Have no fear, O Jacob my servant, and you, Jeshurun, whom I have taken for myself.", "geneva": "Thus sayeth the Lord, that made thee, and formed thee from the wombe: he wil helpe thee. Feare not, O Iaakob, my seruaunt, and thou righteous, whome I haue chosen.", "wycliffe": "The Lord makynge and foryyuynge thee, thin helpere fro the wombe, seith these thingis, My seruaunt, Jacob, nyle thou drede, and thou moost riytful, whom Y chees.", "rotherham": "Thus, saith Yahweh—Who made thee and formed thee from birth, Who helpeth thee: Do not fear O my Servant Jacob, and Jeshurun whom I have chosen;", "darby": "thus saith Jehovah, that made thee, and formed thee from the womb, who helpeth thee, Fear not, Jacob, my servant, and thou, Jeshurun, whom I have chosen.", "twenty": "", "jps": "Thus saith HaShem that made thee, and formed thee from the womb, who will help thee: Fear not, O Jacob My servant, and thou, Jeshurun, whom I have chosen.", "acv": "Thus says Jehovah who made thee, and formed thee from the womb, who will help thee: Fear not, O Jacob my servant, and thou, Jeshurun, whom I have chosen.", "anderson": "", "haweis": "", "noyes": "Thus saith Jehovah, thy Creator, He that formed thee, and hath helped thee from thy birth, Fear not, O Jacob, my servant, O Jeshurun, whom I have chosen.", "webster": "Thus saith the LORD that made thee, and formed thee from the womb, [who] will help thee: Fear not, O Jacob, my servant; and thou, Jesurun, whom I have chosen.", "vulgate": "haec dicit Dominus faciens et formans te ab utero auxiliator tuus noli timere serve meus Iacob et Rectissime quem elegi;", "brenton": "Thus saith the Lord God that made thee, and he that formed thee from the womb; Thou shalt yet be helped: fear not, my servant Jacob; and beloved Israel, whom I have chosen."}}, {"v": 3, "ref": "44:3", "o": "כִּ֤י אֶצָּק מַ֨יִם֙ עַל צָמֵ֔א וְ/נֹזְלִ֖ים עַל יַבָּשָׁ֑ה אֶצֹּ֤ק רוּחִ/י֙ עַל זַרְעֶ֔/ךָ וּ/בִרְכָתִ֖/י עַל צֶאֱצָאֶֽי/ךָ", "en": {"kjv": "For I will pour water upon him that is thirsty, and floods upon the dry ground: I will pour my spirit upon thy seed, and my blessing upon thine offspring:", "web": "For I will pour water on him who is thirsty, and streams on the dry ground. I will pour my Spirit on your seed, and my blessing on your offspring:", "bsb": "For I will pour water on the thirsty land, and currents on the dry ground. I will pour out My Spirit on your descendants, and My blessing on your offspring.", "asv": "For I will pour water upon him that is thirsty, and streams upon the dry ground; I will pour my Spirit upon thy seed, and my blessing upon thine offspring:", "ylt": "For I pour waters on a thirsty one, And floods on a dry land, I pour My Spirit on thy seed, And My blessing on thine offspring.", "dra": "For I will pour out waters upon the thirsty ground, and streams upon the dry land: I will pour out my spirit upon thy seed, and my blessing upon thy stock.", "bbe": "For I will send water on the land needing it, and streams on the dry earth: I will let my spirit come down on your seed, and my blessing on your offspring.", "geneva": "For I will powre water vpon the thirstie, and floods vpon the drie grounde: I will powre my Spirit vpon thy seede, and my blessing vpon thy buddes.", "wycliffe": "For Y schal schede out watris on the thirsti, and floodis on the dry lond; Y schal schede out my spirit on thi seed, and my blessyng on thi generacioun.", "rotherham": "For I will pour, Water upon the thirsty soil, and Floods upon the dry ground,—I will pour My spirit upon thy seed, and My blessing upon thine offspring;", "darby": "For I will pour water upon him that is thirsty, and floods upon the dry ground; I will pour my Spirit upon thy seed, and my blessing upon thine offspring.", "twenty": "", "jps": "For I will pour water upon the thirsty land, and streams upon the dry ground; I will pour My spirit upon thy seed, and My blessing upon thine offspring;", "acv": "For I will pour water upon him who is thirsty, and streams upon the dry ground. I will pour my Spirit upon thy seed, and my blessing upon thine offspring.", "anderson": "", "haweis": "", "noyes": "For I will pour water upon the thirsty land, And streams upon the dry ground. I will pour out my spirit on thy children, And my blessing on thine offspring;", "webster": "For I will pour water upon him that is thirsty, and floods upon the dry ground: I will pour my spirit upon thy seed, and my blessing upon thy offspring:", "vulgate": "effundam enim aquas super sitientem et fluenta super aridam effundam spiritum meum super semen tuum et benedictionem meam super stirpem tuam;", "brenton": "For I will give water to the thirsty that walk in a dry land: I will put my Spirit upon thy seed, and my blessings upon thy children:"}}, {"v": 4, "ref": "44:4", "o": "וְ/צָמְח֖וּ בְּ/בֵ֣ין חָצִ֑יר כַּ/עֲרָבִ֖ים עַל יִבְלֵי מָֽיִם", "en": {"kjv": "And they shall spring up as among the grass, as willows by the water courses.", "web": "and they will spring up among the grass, as willows by the watercourses.", "bsb": "They will sprout among the grass like willows by flowing streams.", "asv": "and they shall spring up among the grass, as willows by the watercourses.", "ylt": "And they have sprung up as among grass, As willows by streams of water.", "dra": "And they shall spring up among the herbs, as willows beside the running waters.", "bbe": "And they will come up like grass in a well-watered field, like water-plants by the streams.", "geneva": "And they shall grow as among the grasse, and as the willowes by the riuers of waters.", "wycliffe": "And thei schulen buriowne among erbis, as salewis bisidis rennynge watris.", "rotherham": "So will they spring up among the grass, As willows by the water-courses:", "darby": "And they shall spring up among the grass, as willows by the water-courses.", "twenty": "", "jps": "And they shall spring up among the grass, as willows by the watercourses.", "acv": "And they shall spring up among the grass, as willows by the watercourses.", "anderson": "", "haweis": "", "noyes": "And they shall grow up, as among grass; As willows by the water-brooks.", "webster": "And they shall spring up [as] among the grass, as willows by the watercourses.", "vulgate": "et germinabunt inter herbas quasi salices iuxta praeterfluentes aquas;", "brenton": "and they shall spring up as grass between brooks, and as willows on the banks of running water."}}, {"v": 5, "ref": "44:5", "o": "זֶ֤ה יֹאמַר֙ לַֽ/יהוָ֣ה אָ֔נִי וְ/זֶ֖ה יִקְרָ֣א בְ/שֵֽׁם יַעֲקֹ֑ב וְ/זֶ֗ה יִכְתֹּ֤ב יָד/וֹ֙ לַֽ/יהוָ֔ה וּ/בְ/שֵׁ֥ם יִשְׂרָאֵ֖ל יְכַנֶּֽה", "en": {"kjv": "One shall say, I am the Lord’s; and another shall call himself by the name of Jacob; and another shall subscribe with his hand unto the Lord, and surname himself by the name of Israel.", "web": "One will say, ‘I am Yahweh’s;’ and another will be called by the name of Jacob; and another will write with his hand ‘to Yahweh,’ and honor the name of Israel.”", "bsb": "One will say, ‘I belong to the LORD,’ another will call himself by the name of Jacob, and still another will write on his hand, ‘The LORD’s,’ and will take the name of Israel.”", "asv": "One shall say, I am Jehovah’s; and another shall call himself by the name of Jacob; and another shall subscribe with his hand unto Jehovah, and surname himself by the name of Israel.", "ylt": "This one saith, For Jehovah I am , And this calleth himself by the name of Jacob, And this one writeth with his hand, `For Jehovah,' and by the name of Israel surnameth himself.", "dra": "One shall say: I am the Lord's, and another shall call himself by the name of Jacob, and another shall subscribe with his hand, To the Lord, and surname himself by the name of Israel.", "bbe": "One will say, I am the Lord's; and another will give himself the name, Jacob; another will put a mark on his hand, I am the Lord's, and another will take the name of Israel for himself.", "geneva": "One shall say, I am the Lordes: another shalbe called by the name of Iaakob: and another shall subscribe with his hand vnto the Lord, and name himselfe by the name of Israel.", "wycliffe": "This man schal seie, Y am of the Lord, and he schal clepe in the name of Jacob; and this man schal write with his hoond to the Lord, and schal be licned in the name of Israel.", "rotherham": "This one, will say Yahweh’s, am I, and That one, will call himself by the name of Jacob, and Yonder one will write on his hand—Yahweh’s, And after the name of Israel, will one entitle himself.", "darby": "One shall say, I am Jehovah's; and another shall call [himself] by the name of Jacob; and another shall write with his hand: [I am] Jehovah's, and surname [himself] by the name of Israel.", "twenty": "", "jps": "One shall say: 'I am HaShem'S'; and another shall call himself by the name of Jacob; and another shall subscribe with his hand unto HaShem, and surname himself by the name of Israel.", "acv": "One shall say, I am Jehovah's, and another shall call himself by the name of Jacob, and another shall subscribe with his hand to Jehovah, and surname himself by the name of Israel.", "anderson": "", "haweis": "", "noyes": "One shall say, \"I belong to Jehovah\"; Another shall call upon the name of Jacob; Another shall write upon his hand, Jehovah’s! And praise the name of Israel.", "webster": "One shall say, I [am] the LORD'S; and another shall call [himself] by the name of Jacob; and another shall subscribe [with] his hand to the LORD, and surname [himself] by the name of Israel.", "vulgate": "iste dicet Domini ego sum et ille vocabit in nomine Iacob et hic scribet manu sua Domino et in nomine Israhel adsimilabitur;", "brenton": "One shall say, I am God's; and another shall call himself by the name of Jacob; and another shall write with his hand, I am God's, and shall call himself by the name of Israel."}}, {"v": 6, "ref": "44:6", "o": "כֹּֽה אָמַ֨ר יְהוָ֧ה מֶֽלֶךְ יִשְׂרָאֵ֛ל וְ/גֹאֲל֖/וֹ יְהוָ֣ה צְבָא֑וֹת אֲנִ֤י רִאשׁוֹן֙ וַ/אֲנִ֣י אַחֲר֔וֹן וּ/מִ/בַּלְעָדַ֖/י אֵ֥ין אֱלֹהִֽים", "en": {"kjv": "Thus saith the Lord the King of Israel, and his redeemer the Lord of hosts; I am the first, and I am the last; and beside me there is no God.", "web": "This is what Yahweh, the King of Israel, and his Redeemer, Yahweh of Armies, says: “I am the first, and I am the last; and besides me there is no God.", "bsb": "Thus says the LORD, the King and Redeemer of Israel, the LORD of Hosts: “I am the first and I am the last, and there is no God but Me.", "asv": "Thus saith Jehovah, the King of Israel, and his Redeemer, Jehovah of hosts: I am the first, and I am the last; and besides me there is no God.", "ylt": "Thus said Jehovah, king of Israel, And his Redeemer, Jehovah of Hosts: `I am the first, and I the last, And besides Me there is no God.", "dra": "Thus saith the Lord the king of Israel, and his redeemer the Lord of hosts: I am the first, and I am the last, and besides me there is no God.", "bbe": "The Lord, the King of Israel, even the Lord of armies who has taken up his cause, says, I am the first and the last, and there is no God but me.", "geneva": "Thus saith the Lord the King of Israel and his redeemer, the Lord of hostes, I am the first, and I am the last, and without me is there no God.", "wycliffe": "The Lord, kyng of Israel, and ayenbiere therof, the Lord of oostis seith these thingis, Y am the firste and Y am the laste, and with outen me is no God.", "rotherham": "Thus saith Yahweh—King of Israel, Even his Redeemer, Yahweh of hosts,—I, am, First, and, I, Last, And besides me, there is no God.", "darby": "Thus saith Jehovah, the King of Israel, and his Redeemer, Jehovah of hosts: I [am] the first, and I [am] the last, and beside me there is noGod.", "twenty": "", "jps": "Thus saith HaShem, the King of Israel, and his Redeemer HaShem of hosts: I am the first, and I am the last, and beside Me there is no G-d.", "acv": "Thus says Jehovah, the King of Israel, and his Redeemer, Jehovah of hosts: I am the first, and I am the last, and besides me there is no God.", "anderson": "", "haweis": "", "noyes": "Thus saith Jehovah, the King of Israel, His redeemer, Jehovah of hosts: I am the first, and I the last, And besides me there is no God.", "webster": "Thus saith the LORD the King of Israel, and his redeemer the LORD of hosts; I [am] the first, and I [am] the last; and besides me [there is] no God.", "vulgate": "haec dicit Dominus rex Israhel et redemptor eius Dominus exercituum ego primus et ego novissimus et absque me non est deus;", "brenton": "Thus saith God the King of Israel, and the God of hosts that delivered him; I am the first, and I am hereafter: beside me there is no God."}}, {"v": 7, "ref": "44:7", "o": "וּ/מִֽי כָמ֣וֹ/נִי יִקְרָ֗א וְ/יַגִּידֶ֤/הָ וְ/יַעְרְכֶ֨/הָ֙ לִ֔/י מִ/שּׂוּמִ֖/י עַם עוֹלָ֑ם וְ/אֹתִיּ֛וֹת וַ/אֲשֶׁ֥ר תָּבֹ֖אנָה יַגִּ֥ידוּ לָֽ/מוֹ", "en": {"kjv": "And who, as I, shall call, and shall declare it, and set it in order for me, since I appointed the ancient people? and the things that are coming, and shall come, let them shew unto them.", "web": "Who is like me? Who will call, and will declare it, and set it in order for me, since I established the ancient people? Let them declare the things that are coming, and that will happen.", "bsb": "Who then is like Me? Let him say so! Let him declare his case before Me, since I established an ancient people. Let him foretell the things to come, and what is to take place.", "asv": "And who, as I, shall call, and shall declare it, and set it in order for me, since I established the ancient people? and the things that are coming, and that shall come to pass, let them declare.", "ylt": "And who as I, doth call and declare it, And arrange it for Me, Since My placing the people of antiquity, And things that are coming, And those that do come, declare they to them?", "dra": "Who is like to me? let him call and declare: and let him set before me the order, since I appointed the ancient people: and the things to come, and that shall be hereafter, let them shew unto them.", "bbe": "If there is one like me, let him come forward and say it, let him make it clear and put it in order before me: who has made clear in the past the things to come? let him make clear the future to me.", "geneva": "And who is like me, that shall call, and shall declare it, and set it in order before me, since I appointed the ancient people? and what is at hand, and what things are to come? let them shewe vnto them.", "wycliffe": "Who is lijk me? clepe he, and telle, and declare ordre to me, sithen Y made elde puple; telle he to hem thingis to comynge, and that schulen be.", "rotherham": "Who then, like me, can call, and declare it, and order it, for me, Seeing that I appointed an age-abiding people,—Or things yet to be, and that shall come to pass, Let them declare on their part.", "darby": "And who, as I, shall call, and shall declare it, and set it in order for me, since I appointed the ancient people? And the coming things, and those that shall happen, let them declare unto them.", "twenty": "", "jps": "And who, as I, can proclaim--let him declare it, and set it in order for Me--since I appointed the ancient people? And the things that are coming, and that shall come to pass, let them declare.", "acv": "And who, as I, shall call, and shall declare it, and set it in order for me, since I established the ancient people? And let them declare the things that are coming, and that shall come to pass.", "anderson": "", "haweis": "", "noyes": "Who like me hath proclaimed the future,—Let him declare it, and set it in order before me!— Since I established the people of old? Let them make known the future, even that which is to come!", "webster": "And who, as I, shall call, and shall declare it, and set it in order for me, since I appointed the ancient people? and the things that are coming, and shall come, let them show to them.", "vulgate": "quis similis mei vocet et adnuntiet et ordinem exponat mihi ex quo constitui populum antiquum ventura et quae futura sunt adnuntient eis;", "brenton": "Who is like me? let him stand, and call, and declare, and prepare for me from the time that I made man for ever; and let them tell you the things that are coming before they arrive."}}, {"v": 8, "ref": "44:8", "o": "אַֽל תִּפְחֲדוּ֙ וְ/אַל תִּרְה֔וּ הֲ/לֹ֥א מֵ/אָ֛ז הִשְׁמַעְתִּ֥י/ךָ וְ/הִגַּ֖דְתִּי וְ/אַתֶּ֣ם עֵדָ֑/י הֲ/יֵ֤שׁ אֱל֨וֹהַּ֙ מִ/בַּלְעָדַ֔/י וְ/אֵ֥ין צ֖וּר בַּל יָדָֽעְתִּי", "en": {"kjv": "Fear ye not, neither be afraid: have not I told thee from that time, and have declared it? ye are even my witnesses. Is there a God beside me? yea, there is no God; I know not any.", "web": "Don’t fear, neither be afraid. Haven’t I declared it to you long ago, and shown it? You are my witnesses. Is there a God besides me? Indeed, there is not. I don’t know any other Rock.”", "bsb": "Do not tremble or fear. Have I not told you and declared it long ago? You are My witnesses! Is there any God but Me? There is no other Rock; I know not one.”", "asv": "Fear ye not, neither be afraid: have I not declared unto thee of old, and showed it? and ye are my witnesses. Is there a God besides me? yea, there is no Rock; I know not any.", "ylt": "Fear not, nor be afraid, Have I not from that time caused thee to hear, and declared? And ye are My witnesses, Is there a God besides Me? yea, there is none, A Rock I have not known.", "dra": "Fear ye not, neither be ye troubled from that time I have made thee to hear, and have declared: you are my witnesses. Is there a God besides me, a maker, whom I have not known?", "bbe": "Have no fear, be strong in heart; have I not made it clear to you in the past, and let you see it? and you are my witnesses. Is there any God but me, or a Rock of whom I have no knowledge?", "geneva": "Feare ye not, neither be afraide: haue not I tolde thee of olde, and haue declared it? you are euen my witnesses, whether there be a God beside me, and that there is no God that I knowe not.", "wycliffe": "Nyle ye drede, nether be ye disturblid; fro that tyme Y made thee for to here, and Y telde; ye ben my witnessis. Whethir a God is with out me, and a formere, whom Y knew not?", "rotherham": "Do not ye dread, nor yet be alarmed, Have I not from olden time, told thee and declared? So that, ye, are my witnesses,—Whether there is a GOD besides me? Or is no Rock—I knew of none!", "darby": "Fear not, neither be afraid. Have I not caused thee to hear from that time, and have declared it? and ye are my witnesses. Is there aGod beside me? yea, there is no Rock: I know not any.", "twenty": "", "jps": "Fear ye not, neither be afraid; have I not announced unto thee of old, and declared it? And ye are My witnesses. Is there a G-d beside Me? Yea, there is no Rock; I know not any.", "acv": "Fear ye not, nor be afraid. Have I not declared to thee of old, and shown it? And ye are my witnesses. Is there a God besides me? Yea, there is no Rock. I know not any.", "anderson": "", "haweis": "", "noyes": "Fear ye not, neither be ye afraid! Have I not declared and made it known to you of old? Ye are my witnesses; Is there a God beside me? Yea, there is no other rock; I know not any.", "webster": "Fear ye not, neither be afraid: have not I told thee from that time, and have declared [it]? ye [are] even my witnesses. Is there a God besides me? verily [there is] no God; I know not [any].", "vulgate": "nolite timere neque conturbemini ex tunc audire te feci et adnuntiavi vos estis testes mei numquid est deus absque me et formator quem ego non noverim;", "brenton": "Hide not yourselves, nor go astray: have ye not heard from the beginning, and have not I told you? ye are witnesses if there is a God beside me."}}, {"v": 9, "ref": "44:9", "o": "יֹֽצְרֵי פֶ֤סֶל כֻּלָּ/ם֙ תֹּ֔הוּ וַ/חֲמוּדֵי/הֶ֖ם בַּל יוֹעִ֑ילוּ וְ/עֵדֵי/הֶ֣ם הֵׄ֗מָּׄהׄ בַּל יִרְא֛וּ וּ/בַל יֵדְע֖וּ לְמַ֥עַן יֵבֹֽשׁוּ", "en": {"kjv": "They that make a graven image are all of them vanity; and their delectable things shall not profit; and they are their own witnesses; they see not, nor know; that they may be ashamed.", "web": "Everyone who makes an engraved image is vain. The things that they delight in will not profit. Their own witnesses don’t see, nor know, that they may be disappointed.", "bsb": "All makers of idols are nothing, and the things they treasure are worthless. Their witnesses fail to see or comprehend, so they are put to shame.", "asv": "They that fashion a graven image are all of them vanity; and the things that they delight in shall not profit; and their own witnesses see not, nor know: that they may be put to shame.", "ylt": "Framers of a graven image are all of them emptiness, And their desirable things do not profit, And their own witnesses they are , They see not, nor know, that they may be ashamed.", "dra": "The makers of idols are all of them nothing, and their best beloved things shall not profit them. They are their witnesses, that they do not see, nor understand, that they may be ashamed.", "bbe": "Those who make a pictured image are all of them as nothing, and the things of their desire will be of no profit to them: and their servants see not, and have no knowledge; so they will be put to shame.", "geneva": "All they that make an image, are vanitie, and their delectable things shall nothing profite: and they are their owne witnesses, that they see not nor know: therefore they shalbe confounded.", "wycliffe": "Alle the fourmeris of an idol ben no thing, and the moost louyd thingis of hem schulen not profite; thei ben witnessis of tho, that tho seen not, nether vndurstonden, that thei be schent.", "rotherham": "The fashioners of an image—all of them, are emptiness, And, the things they delight in, cannot profit,—And, their, witnesses, they, neither see nor know, That they may be ashamed.", "darby": "They that form a graven image are all of them vanity, and their delectable things are of no profit; and they are their own witnesses: they see not, nor know; — that they may be ashamed.", "twenty": "", "jps": "They that fashion a graven image are all of them vanity, and their delectable things shall not profit; and their own witnesses see not, nor know; that they may be ashamed.", "acv": "Those who fashion a graven image are all of them vanity. And the things that they delight in shall not profit. And their own witnesses see not, nor know, that they may be put to shame.", "anderson": "", "haweis": "", "noyes": "They that make a graven image are all of them vanity, And their valued works are profitable for nothing; They are their own witnesses; They neither see nor understand, So that they may be ashamed.", "webster": "They that make a graven image [are] all of them vanity; and their delectable things shall not profit; and they [are] their own witnesses; they see not, nor know; that they may be ashamed.", "vulgate": "plastae idoli omnes nihil sunt et amantissima eorum non proderunt eis ipsi sunt testes eorum quia non vident neque intellegunt ut confundantur;", "brenton": "But they that framed false gods did not then hearken; and they that graved images are all vain, performing their own desires, which shall not profit them, but they shall be ashamed"}}, {"v": 10, "ref": "44:10", "o": "מִֽי יָצַ֥ר אֵ֖ל וּ/פֶ֣סֶל נָסָ֑ךְ לְ/בִלְתִּ֖י הוֹעִֽיל", "en": {"kjv": "Who hath formed a god, or molten a graven image that is profitable for nothing?", "web": "Who has fashioned a god, or molds an image that is profitable for nothing?", "bsb": "Who fashions a god or casts an idol which profits him nothing?", "asv": "Who hath fashioned a god, or molten an image that is profitable for nothing?", "ylt": "Who hath formed a god, And a molten image poured out--not profitable?", "dra": "Who hath formed a god, and made a graven thing that is profitable for nothing?", "bbe": "Whoever makes a god, makes nothing but a metal image in which there is no profit.", "geneva": "Who hath made a god, or molten an image, that is profitable for nothing?", "wycliffe": "Who fourmyde a god, and yetide an ymage, not profitable to ony thing?", "rotherham": "Who hath fashioned a GOD, Oran image, hath molten? It cannot profit!", "darby": "Who hath formed agod, or molten a graven image that is profitable for nothing?", "twenty": "", "jps": "Who hath fashioned a god, or molten an image that is profitable for nothing?", "acv": "Who has fashioned a god, or molded an image that is profitable for nothing?", "anderson": "", "haweis": "", "noyes": "Who hath formed a god, And cast a graven image, that is profitable for nothing?", "webster": "Who hath formed a god, or cast a graven image [that] is profitable for nothing?", "vulgate": "quis formavit deum et sculptile conflavit ad nihil utile;", "brenton": "that form a god, and all that grave worthless things:"}}, {"v": 11, "ref": "44:11", "o": "הֵ֤ן כָּל חֲבֵרָי/ו֙ יֵבֹ֔שׁוּ וְ/חָרָשִׁ֥ים הֵ֖מָּה מֵֽ/אָדָ֑ם יִֽתְקַבְּצ֤וּ כֻלָּ/ם֙ יַֽעֲמֹ֔דוּ יִפְחֲד֖וּ יֵבֹ֥שׁוּ יָֽחַד", "en": {"kjv": "Behold, all his fellows shall be ashamed: and the workmen, they are of men: let them all be gathered together, let them stand up; yet they shall fear, and they shall be ashamed together.", "web": "Behold, all his fellows will be disappointed; and the workmen are mere men. Let them all be gathered together. Let them stand up. They will fear. They will be put to shame together.", "bsb": "Behold, all his companions will be put to shame, for the craftsmen themselves are only human. Let them all assemble and take their stand; they will all be brought to terror and shame.", "asv": "Behold, all his fellows shall be put to shame; and the workmen, they are of men: let them all be gathered together, let them stand up; they shall fear, they shall be put to shame together.", "ylt": "Lo, all his companions are ashamed, As to artisans--they are of men, All of them gather together, they stand up, They fear, they are ashamed together.", "dra": "Behold, all the partakers thereof shall be confounded: for the makers are men: they shall all assemble together, they shall stand and fear, and shall be confounded together.", "bbe": "Truly, all those who make use of secret arts will be put to shame, and their words of power are only words of men: let them all come forward together; they will all be in fear and be put to shame.", "geneva": "Beholde, all that are of the fellowship thereof, shall be confounded: for the workemen themselues are men: let them all be gathered together, and stand vp, yet they shall feare, and be confounded together.", "wycliffe": "Lo! alle the parteneris therof schulen be schent; for the smythis ben of men. Whanne alle schulen come, thei schulen stonde, and schulen drede, and schulen be schent togidere.", "rotherham": "Lo! all his partners, turn pale, Even, the artificers themselves, are of the sons of earth,—Let them gather themselves together—all of them. Let them take their stand, Let them dread, and turn pale, together!", "darby": "Behold, all his fellows shall be ashamed; and the workmen are but men. Let them all be gathered together, let them stand up: they shall fear, they shall be ashamed together.", "twenty": "", "jps": "Behold, all the fellows thereof shall be ashamed; and the craftsmen skilled above men; let them all be gathered together, let them stand up; they shall fear, they shall be ashamed together.", "acv": "Behold, all his fellows shall be put to shame, and the workmen. They are of men. Let them all be gathered together. Let them stand up. They shall fear. They shall be put to shame together.", "anderson": "", "haweis": "", "noyes": "Behold, all his fellows shall be ashamed; The workmen are themselves mortal men; They shall all be assembled; they shall stand up; They shall tremble, and be put to shame together!", "webster": "Behold, all his fellows shall be ashamed: and the workmen, they [are] of men: let them all be assembled, let them stand up; [yet] they shall fear, [and] they shall be ashamed together.", "vulgate": "ecce omnes participes eius confundentur fabri enim sunt ex hominibus convenient omnes stabunt et pavebunt et confundentur simul;", "brenton": "and all by whom they were made are withered: yea, let all the deaf be gathered from among men, and let them stand together; and let them be ashamed and confounded together:"}}, {"v": 12, "ref": "44:12", "o": "חָרַ֤שׁ בַּרְזֶל֙ מַֽעֲצָ֔ד וּ/פָעַל֙ בַּ/פֶּחָ֔ם וּ/בַ/מַּקָּב֖וֹת יִצְּרֵ֑/הוּ וַ/יִּפְעָלֵ֨/הוּ֙ בִּ/זְר֣וֹעַ כֹּח֔/וֹ גַּם רָעֵב֙ וְ/אֵ֣ין כֹּ֔חַ לֹא שָׁ֥תָה מַ֖יִם וַ/יִּיעָֽף", "en": {"kjv": "The smith with the tongs both worketh in the coals, and fashioneth it with hammers, and worketh it with the strength of his arms: yea, he is hungry, and his strength faileth: he drinketh no water, and is faint.", "web": "The blacksmith takes an ax, works in the coals, fashions it with hammers, and works it with his strong arm. He is hungry, and his strength fails; he drinks no water, and is faint.", "bsb": "The blacksmith takes a tool and labors over the coals; he fashions an idol with hammers and forges it with his strong arms. Yet he grows hungry and loses his strength; he fails to drink water and grows faint.", "asv": "The smithmakethan axe, and worketh in the coals, and fashioneth it with hammers, and worketh it with his strong arm: yea, he is hungry, and his strength faileth; he drinketh no water, and is faint.", "ylt": "He hath wrought iron with an axe, And hath wrought with coals, And with hammers doth form it, And doth work it by his powerful arm, Yea, he is hungry, and there is no power, He doth not drink water, and he is wearied.", "dra": "The smith hath wrought with his file, with coals, and with hammers he hath formed it, and hath wrought with the strength of his arm: he shall hunger and faint, he shall drink no water, and shall be weary.", "bbe": "The iron-worker is heating the metal in the fire, giving it form with his hammers, and working on it with his strong arm: then for need of food his strength gives way, and for need of water he becomes feeble.", "geneva": "The smith taketh an instrument, and worketh in the coles, and facioneth it with hammers, and worketh it with the strength of his armes: yea, he is an hungred, and his strength faileth: he drinketh no water, and is faint.", "wycliffe": "A smith wrouyte with a file; he fourmyde it in coolis, and in hameris, and he wrouyte with the arm of his strengthe. He schal be hungri, and he schal faile; he schal not drynke watre, and he schal be feynt.", "rotherham": "As for the smith, [with his] cutting-tool,—When he hath wrought in the live coals, And, with hammers, hath fashioned it,—And hath wrought it with his strong arm, Anon he is hungry, and hath no strength, He hath drunk no water and so hath become faint!", "darby": "The iron-smith [hath] a chisel, and he worketh in the coals, and he fashioneth it with hammers, and worketh it with his strong arm; — but he is hungry, and his strength faileth; he hath not drunk water, and he is faint.", "twenty": "", "jps": "The smith maketh an axe, and worketh in the coals, and fashioneth it with hammers, and worketh it with his strong arm; yea, he is hungry, and his strength faileth; he drinketh no water, and is faint.", "acv": "The smith makes an axe, and works in the coals, and fashions it with hammers, and works it with his strong arm. Yea, he is hungry, and his strength fails. He drinks no water, and is faint.", "anderson": "", "haweis": "", "noyes": "The smith prepareth an axe in the coals, And fashioneth it with hammers, And worketh it with his strong arm; He becometh hungry, and his strength faileth; He drinketh no water, and is faint.", "webster": "The smith with the tongs both worketh in the coals, and fashioneth it with hammers, and worketh it with the strength of his arms: yes, he is hungry, and his strength faileth: he drinketh no water, and is faint.", "vulgate": "faber ferrarius lima operatus est in prunis et in malleis formavit illud et operatus est in brachio fortitudinis suae esuriet et deficiet non bibet aquam et lassescet;", "brenton": "For the artificer sharpens the iron; he fashions the idol with an axe, and fixes it with an awl, and fashions it with the strength of his arm: and he will be hungry and weak, and will drink no water."}}, {"v": 13, "ref": "44:13", "o": "חָרַ֣שׁ עֵצִים֮ נָ֣טָה קָו֒ יְתָאֲרֵ֣/הוּ בַ/שֶּׂ֔רֶד יַעֲשֵׂ֨/הוּ֙ בַּ/מַּקְצֻע֔וֹת וּ/בַ/מְּחוּגָ֖ה יְתָאֳרֵ֑/הוּ וַֽ/יַּעֲשֵׂ֨/הוּ֙ כְּ/תַבְנִ֣ית אִ֔ישׁ כְּ/תִפְאֶ֥רֶת אָדָ֖ם לָ/שֶׁ֥בֶת בָּֽיִת", "en": {"kjv": "The carpenter stretcheth out his rule; he marketh it out with a line; he fitteth it with planes, and he marketh it out with the compass, and maketh it after the figure of a man, according to the beauty of a man; that it may remain in the house.", "web": "The carpenter stretches out a line. He marks it out with a pencil. He shapes it with planes. He marks it out with compasses, and shapes it like the figure of a man, with the beauty of a man, to reside in a house.", "bsb": "The woodworker extends a measuring line; he marks it out with a stylus; he shapes it with chisels and outlines it with a compass. He fashions it in the likeness of man, like man in all his glory, that it may dwell in a shrine.", "asv": "The carpenter stretcheth out a line; he marketh it out with a pencil; he shapeth it with planes, and he marketh it out with the compasses, and shapeth it after the figure of a man, according to the beauty of a man, to dwell in a house.", "ylt": "He hath wrought with wood, He hath stretched out a rule, He doth mark it out with a line, He maketh it with carving tools, And with a compass he marketh it out, And maketh it according to the form of a man, According to the beauty of a man, To remain in the house.", "dra": "The carpenter hath stretched out his rule, he hath formed it with a plane: he hath made it with corners, and hath fashioned it round with the compass: and he hath made the image of a man as it were a beautiful man dwelling in a house.", "bbe": "The woodworker is measuring out the wood with his line, marking it out with his pencil: after smoothing it with his plane, and making circles on it with his instrument, he gives it the form and glory of a man, so that it may be placed in the house.", "geneva": "The carpenter stretcheth out a line: he facioneth it with a red thread, he planeth it, and he purtreyeth it with the compasse, and maketh it after the figure of a man, and according to the beautie of a man that it may remaine in an house.", "wycliffe": "A carpenter stretchide forth a reule, he fourmyde it with an adese; he made it in the corner places, and he turnede it in cumpas; and he made the ymage of a man, as a fair man, dwellynge in the hous.", "rotherham": "As for the carpenter,—He hath stretched out a line hath drawn it with a pencil, Hath made it with carving tools, With compasses, hath rounded it,—And so hath made it after the figure of a great man, After the beauty of a son of earth, that it may remain in a house!", "darby": "The worker in wood stretcheth out a line; he marketh it out with red chalk; he formeth it with sharp tools, and he marketh it out with the compass, and maketh it after the figure of a man, according to the beauty of man: that it may remain in the house.", "twenty": "", "jps": "The carpenter stretcheth out a line; he marketh it out with a pencil; he fitteth it with planes, and he marketh it out with the compasses, and maketh it after the figure of a man, according to the beauty of a man, to dwell in the house.", "acv": "The carpenter stretches out a line. He marks it out with a pencil. He shapes it with planes. And he marks it out with the compasses, and shapes it after the figure of a man, according to the beauty of a man, to dwell in a house.", "anderson": "", "haweis": "", "noyes": "The carpenter stretcheth out the line; He marketh out the form of it with the sharp tool; He formeth it with planes; He marketh it with the compass; He maketh it in the figure of a man, With the beauty of a man, To dwell in a house.", "webster": "The carpenter stretcheth out [his] rule; he marketh it out with a line; he fitteth it with planes, and he marketh it out with the compass, and maketh it after the figure of a man, according to the beauty of a man; that it may remain in the house.", "vulgate": "artifex lignarius extendit normam formavit illud in runcina fecit illud in angularibus et in circino tornavit illud et fecit imaginem viri quasi speciosum hominem habitantem in domo;", "brenton": "The artificer having chosen a piece of wood, marks it out with a rule, and fits it with glue, and makes it as the form of a man, and as the beauty of a man, to set it up in the house."}}, {"v": 14, "ref": "44:14", "o": "לִ/כְרָת ל֣/וֹ אֲרָזִ֔ים וַ/יִּקַּ֤ח תִּרְזָה֙ וְ/אַלּ֔וֹן וַ/יְאַמֶּץ ל֖/וֹ בַּ/עֲצֵי יָ֑עַר נָטַ֥ע אֹ֖רֶ וְ/גֶ֥שֶׁם יְגַדֵּֽל", "en": {"kjv": "He heweth him down cedars, and taketh the cypress and the oak, which he strengtheneth for himself among the trees of the forest: he planteth an ash, and the rain doth nourish it.", "web": "He cuts down cedars for himself, and takes the cypress and the oak, and strengthens for himself one among the trees of the forest. He plants a fir tree, and the rain nourishes it.", "bsb": "He cuts down cedars or retrieves a cypress or oak. He lets it grow strong among the trees of the forest. He plants a laurel, and the rain makes it grow.", "asv": "He heweth him down cedars, and taketh the holm-tree and the oak, and strengtheneth for himself one among the trees of the forest: he planteth a fir-tree, and the rain doth nourish it.", "ylt": "Cutting down to himself cedars, He taketh also a cypress, and an oak, And he strengtheneth it for himself Among the trees of a forest, He hath planted an ash, and the shower doth nourish it .", "dra": "He hath cut down cedars, taken the holm, and the oak that stood among the trees of the forest: he hath planted the pine tree, which the rain hath nourished.", "bbe": "He has cedars cut down for himself, he takes an oak and lets it get strong among the trees of the wood; he has an ash-tree planted, and the rain gives it growth.", "geneva": "He will hewe him downe cedars, and take the pine tree and the oke, and taketh courage among the trees of the forest: he planteth a firre tree, and the raine doeth nourish it.", "wycliffe": "He kittide doun cedris, he took an hawthorn, and an ook, that stood among the trees of the forest; he plauntide a pyne apple tre, which he nurschide with reyn,", "rotherham": "When one was cutting him down cedars, Then took he a holm-tree and an oak, And secured them for himself, among the trees of the forest,—He planted a fir-tree and the pouring rain made it grow;", "darby": "When he heweth him down cedars, he taketh also a holm-oak and a terebinth — he chooseth for himself among the trees of the forest: he planteth a pine, and the rain maketh [it] grow.", "twenty": "", "jps": "He heweth him down cedars, and taketh the ilex and the oak, and strengtheneth for himself one among the trees of the forest; he planteth a bay-tree, and the rain doth nourish it.", "acv": "He hews down cedars for him, and takes the holm tree and the oak, and strengthens for himself one among the trees of the forest. He plants a fir tree, and the rain nourishes it.", "anderson": "", "haweis": "", "noyes": "He heweth him down cedars; He taketh the ilex and the oak; He chooseth for himself among the trees of the forest; He planteth the ash, and the rain matureth it;", "webster": "He heweth down cedars for himself, and taketh the cypress and the oak, which he strengtheneth for himself among the trees of the forest: he planteth an ash, and the rain doth nourish [it].", "vulgate": "succidit cedros tulit ilicem et quercum quae steterat inter ligna saltus plantavit pinum quam pluvia nutrivit;", "brenton": "He cuts wood out of the forest, which the Lord planted, even a pine tree, and the rain made it grow,"}}, {"v": 15, "ref": "44:15", "o": "וְ/הָיָ֤ה לְ/אָדָם֙ לְ/בָעֵ֔ר וַ/יִּקַּ֤ח מֵ/הֶם֙ וַ/יָּ֔חָם אַף יַשִּׂ֖יק וְ/אָ֣פָה לָ֑חֶם אַף יִפְעַל אֵל֙ וַ/יִּשְׁתָּ֔חוּ עָשָׂ֥/הוּ פֶ֖סֶל וַ/יִּסְגָּד לָֽ/מוֹ", "en": {"kjv": "Then shall it be for a man to burn: for he will take thereof, and warm himself; yea, he kindleth it, and baketh bread; yea, he maketh a god, and worshippeth it; he maketh it a graven image, and falleth down thereto.", "web": "Then it will be for a man to burn; and he takes some of it, and warms himself. Yes, he burns it, and bakes bread. Yes, he makes a god, and worships it; he makes it an engraved image, and falls down to it.", "bsb": "It serves as fuel for man. He takes some of it to warm himself, and he kindles a fire and bakes his bread; he even fashions it into a god and worships it; he makes an idol and bows down to it.", "asv": "Then shall it be for a man to burn; and he taketh thereof, and warmeth himself; yea, he kindleth it, and baketh bread: yea, he maketh a god, and worshippeth it; he maketh it a graven image, and falleth down thereto.", "ylt": "And it hath been for man to burn, And he taketh of them, and becometh warm, Yea, he kindleth it , and hath baked bread, Yea, he maketh a god, and boweth himself, He hath made it a graven image, And he falleth down to it.", "dra": "And it hath served men for fuel: he took thereof, and warmed himself: and he kindled it, and baked bread: but of the rest he made a god, and adored it: he made a graven thing, and bowed down before it.", "bbe": "Then it will be used to make a fire, so that a man may get warm; he has the oven heated with it and makes bread: he makes a god with it, to which he gives worship: he makes a pictured image out of it, and goes down on his face before it.", "geneva": "And man burneth thereof: for he will take thereof and warme himselfe: he also kindleth it and baketh bread, yet he maketh a god, and worshippeth it: he maketh it an idole and boweth vnto it.", "wycliffe": "and it was maad in to fier to men. He took of tho, and was warmed, and he brente, and bakide looues; but of the residue he wrouyte a god, and worschipide it, and he made a grauun ymage, and he was bowid bifore that.", "rotherham": "So it serveth for a man to burn, And he hath taken of the branches and warmed himself, Also he kindleth a fire, and baketh bread,—Also he maketh a GOD, and hath bowed himself down, Hath made of it a carved image, and adored it:", "darby": "And it shall be for a man to burn, and he taketh thereof, and warmeth himself; he kindleth it also, and baketh bread; he maketh also agod, and worshippeth it; he maketh it a graven image, and falleth down thereto.", "twenty": "", "jps": "Then a man useth it for fuel; and he taketh thereof, and warmeth himself; yea, he kindleth it, and baketh bread; yea, he maketh a god, and worshippeth it; he maketh it a graven image, and falleth down thereto.", "acv": "Then it shall be for a man to burn. And he takes of it, and warms himself. Yea, he kindles it, and bakes bread. Yea, he makes a god, and worships it. He makes it a graven image, and falls down to it.", "anderson": "", "haweis": "", "noyes": "These are fuel for man; He taketh thereof and warmeth himself; He kindleth with it, and baketh bread; A god also he formeth of it, and worshippeth it; A graven image, and falleth down before it.", "webster": "Then shall it be for a man to burn: for he will take of it, and warm himself; indeed he kindleth [it], and baketh bread; yes, he maketh a god, and worshipeth [it]; he maketh it a graven image, and falleth down to it.", "vulgate": "et facta est hominibus in focum sumpsit ex eis et calefactus est et succendit et coxit panes de reliquo autem operatus est deum et adoravit fecit sculptile et curvatus est ante illud;", "brenton": "that it might be for men to burn: and having taken part of it he warms himself; yea, they burn part of it, and bake loaves thereon; and of the rest they make for themselves gods, and they worship them."}}, {"v": 16, "ref": "44:16", "o": "חֶצְי/וֹ֙ שָׂרַ֣ף בְּמוֹ אֵ֔שׁ עַל חֶצְי/וֹ֙ בָּשָׂ֣ר יֹאכֵ֔ל יִצְלֶ֥ה צָלִ֖י וְ/יִשְׂבָּ֑ע אַף יָחֹם֙ וְ/יֹאמַ֣ר הֶאָ֔ח חַמּוֹתִ֖י רָאִ֥יתִי אֽוּר", "en": {"kjv": "He burneth part thereof in the fire; with part thereof he eateth flesh; he roasteth roast, and is satisfied: yea, he warmeth himself, and saith, Aha, I am warm, I have seen the fire:", "web": "He burns part of it in the fire. With part of it, he eats meat. He roasts a roast, and is satisfied. Yes, he warms himself, and says, “Aha! I am warm. I have seen the fire.”", "bsb": "He burns half of it in the fire, and he roasts meat on that half. He eats the roast and is satisfied. Indeed, he warms himself and says, “Ah! I am warm; I see the fire.”", "asv": "He burneth part thereof in the fire; with part thereof he eateth flesh; he roasteth roast, and is satisfied; yea, he warmeth himself, and saith, Aha, I am warm, I have seen the fire.", "ylt": "Half of it he hath burnt in the fire, By this half of it he eateth flesh, He roasteth a roasting, and is satisfied, Yea, he is warm, and saith: `Aha, I have become warm, I have enjoyed the light.", "dra": "Part of it he burnt with fire, and with part of it he dressed his meat: he boiled pottage, and was filled, and was warmed, and said: Aha, I am warm, I have seen the fire.", "bbe": "With part of it he makes a fire, and on the fire he gets meat cooked and takes a full meal: he makes himself warm, and says, Aha! I am warm, I have seen the fire:", "geneva": "He burneth the halfe thereof euen in the fire, and vpon the halfe thereof he eateth flesh: he rosteth the roste and is satisfied: also he warmeth himselfe and sayth, Aha, I am warme, I haue bene at the fire.", "wycliffe": "He brente the myddil therof with fier, and of the myddil therof he sethide fleischis, and eet; he sethide potage, and was fillid; and he was warmed, and he seide, Wel!", "rotherham": "The half thereof, hath he burned in the fire, Over half thereof, he eateth flesh, He roasteth roast, that he may be satisfied,—Also he warmeth himself, and saith, Aha, I am warm, I have seen a blaze;", "darby": "He burneth part thereof in the fire; with part thereof he eateth flesh, he roasteth roast, and is satisfied; yea, he is warm, and saith, Aha, I am become warm, I have seen the fire.", "twenty": "", "jps": "He burneth the half thereof in the fire; with the half thereof he eateth flesh; he roasteth roast, and is satisfied; yea, he warmeth himself, and saith: 'Aha, I am warm, I have seen the fire';", "acv": "He burns part of it in the fire. With part of it he eats flesh. He roasts roast, and is satisfied. Yea, he warms himself, and says, Aha, I am warm, I have seen the fire.", "anderson": "", "haweis": "", "noyes": "Half of it he burneth with fire; With half of it he eateth flesh; He roasteth meat, and satisfieth himself; He also warmeth himself, and saith, Aha! I am warm; I feel the fire.", "webster": "He burneth part of it in the fire; with part of it he eateth flesh; he roasteth meat, and is satisfied: yes, he warmeth [himself], and saith, Aha, I am warm, I have seen the fire:", "vulgate": "medium eius conbusit igni et de medio eius carnes comedit coxit pulmentum et saturatus est et calefactus est et dixit va calefactus sum vidi focum;", "brenton": "Half thereof he burns in the fire, and with half of it he bakes loaves on the coals; and having roasted flesh on it he eats, and is satisfied, and having warmed himself he says, I am comfortable, for I have warmed myself, and have seen the fire."}}, {"v": 17, "ref": "44:17", "o": "וּ/שְׁאֵ֣רִית֔/וֹ לְ/אֵ֥ל עָשָׂ֖ה לְ/פִסְל֑/וֹ יסגוד יִסְגָּד ל֤/וֹ וְ/יִשְׁתַּ֨חוּ֙ וְ/יִתְפַּלֵּ֣ל אֵלָ֔י/ו וְ/יֹאמַר֙ הַצִּילֵ֔/נִי כִּ֥י אֵלִ֖/י אָֽתָּה", "en": {"kjv": "And the residue thereof he maketh a god, even his graven image: he falleth down unto it, and worshippeth it, and prayeth unto it, and saith, Deliver me; for thou art my god.", "web": "The rest of it he makes into a god, even his engraved image. He bows down to it and worships, and prays to it, and says, “Deliver me; for you are my god!”", "bsb": "From the rest he makes a god, his graven image. He bows down to it and worships; he prays to it and says, “Save me, for you are my god.”", "asv": "And the residue thereof he maketh a god, even his graven image; he falleth down unto it and worshippeth, and prayeth unto it, and saith, Deliver me; for thou art my god.", "ylt": "And its remnant for a god he hath made--For his graven image, He falleth down to it, and worshippeth, And prayeth unto it, and he saith, `Deliver me, for my god thou art .'", "dra": "But the residue thereof he made a god, and a graven thing for himself: he boweth down before it, and adoreth it, and prayeth unto it, saying: Deliver me, for thou art my God.", "bbe": "And the rest of it he makes into a god, even his pictured image: he goes down on his face before it, giving worship to it, and making prayer to it, saying, Be my saviour; for you are my god.", "geneva": "And the residue thereof he maketh a god, euen his idole: he boweth vnto it, and worshippeth and prayeth vnto it, and sayeth, Deliuer me: for thou art my god.", "wycliffe": "Y am warmed; Y siy fier. Forsothe the residue therof he made a god, and a grauun ymage to hym silf; he is bowide bifore that, and worschipith that, and bisechith, and seith, Delyuere thou me, for thou art my god.", "rotherham": "And the residue thereof, Into a GOD, he maketh, Into his carved image,—Adoreth it, and boweth down and prayeth unto it, And saith Deliver me, for, my GOD, thou art!", "darby": "And with the remainder thereof he maketh agod, his graven image; he falleth down unto it, and worshippeth it, and prayeth unto it, and saith, Deliver me, for thou art mygod.", "twenty": "", "jps": "And the residue thereof he maketh a god, even his graven image; he falleth down unto it and worshippeth, and prayeth unto it, and saith: 'Deliver me, for thou art my god.'", "acv": "And the residue of it he makes a god, even his graven image. He falls down to it and worships, and prays to it, and says, Deliver me, for thou are my god.", "anderson": "", "haweis": "", "noyes": "Of the residue he maketh a god, even his graven image; He falleth down before it and worshippeth it, And prayeth to it, and saith, \"Deliver me, for thou art my God!\"", "webster": "And the residue of it he maketh a god, [even] his graven image: he falleth down to it, and worshipeth [it], and prayeth to it, and saith, Deliver me; for thou [art] my god.", "vulgate": "reliquum autem eius deum fecit sculptile sibi curvatur ante illud et adorat illud et obsecrat dicens libera me quia deus meus es tu;", "brenton": "And the rest he makes a graven god, and worships, and prays, saying, Deliver me; for thou art my God."}}, {"v": 18, "ref": "44:18", "o": "לֹ֥א יָדְע֖וּ וְ/לֹ֣א יָבִ֑ינוּ כִּ֣י טַ֤ח מֵֽ/רְאוֹת֙ עֵֽינֵי/הֶ֔ם מֵ/הַשְׂכִּ֖יל לִבֹּתָֽ/ם", "en": {"kjv": "They have not known nor understood: for he hath shut their eyes, that they cannot see; and their hearts, that they cannot understand.", "web": "They don’t know, neither do they consider: for he has shut their eyes, that they can’t see; and their hearts, that they can’t understand.", "bsb": "They do not comprehend or discern, for He has shut their eyes so they cannot see and closed their minds so they cannot understand.", "asv": "They know not, neither do they consider: for he hath shut their eyes, that they cannot see; and their hearts, that they cannot understand.", "ylt": "They have not known, nor do they understand, For He hath daubed their eyes from seeing, Their heart from acting wisely.", "dra": "They have not known, nor understood: for their eyes are covered that they may not see, and that they may not understand with their heart.", "bbe": "They have no knowledge or wisdom; for he has put a veil over their eyes, so that they may not see; and on their hearts, so that they may not give attention.", "geneva": "They haue not knowen, nor vnderstand: for God hath shut their eyes that they cannot see, and their heartes, that they cannot vnderstand.", "wycliffe": "Thei knewen not, nether vndurstoden, for thei han foryete, that her iye se not, and that thei vndurstonde not with her herte.", "rotherham": "They have not taken note, neither can they perceive,—He hath besmeared—past seeing—their eyes, Past understanding, their hearts;", "darby": "They have no knowledge, and understand not; for he hath plastered their eyes, that they may not see; and their hearts, that they may not understand.", "twenty": "", "jps": "They know not, neither do they understand; for their eyes are bedaubed, that they cannot see, and their hearts, that they cannot understand.", "acv": "They do not know, nor do they consider. For he has shut their eyes, that they cannot see, and their hearts, that they cannot understand.", "anderson": "", "haweis": "", "noyes": "They know not, neither understand; For their eyes are closed up, that they cannot see, And their hearts, that they cannot understand.", "webster": "They have not known nor understood: for he hath shut their eyes, that they cannot see; [and] their hearts, that they cannot understand.", "vulgate": "nescierunt neque intellexerunt lutati enim sunt ne videant oculi eorum et ne intellegant corde suo;", "brenton": "They have no understanding to perceive; for they have been blinded so that they should not see with their eyes, nor perceive with their heart."}}, {"v": 19, "ref": "44:19", "o": "וְ/לֹא יָשִׁ֣יב אֶל לִבּ֗/וֹ וְ/לֹ֨א דַ֥עַת וְ/לֹֽא תְבוּנָה֮ לֵ/אמֹר֒ חֶצְי֞/וֹ שָׂרַ֣פְתִּי בְמוֹ אֵ֗שׁ וְ֠/אַף אָפִ֤יתִי עַל גֶּחָלָי/ו֙ לֶ֔חֶם אֶצְלֶ֥ה בָשָׂ֖ר וְ/אֹכֵ֑ל וְ/יִתְר/וֹ֙ לְ/תוֹעֵבָ֣ה אֶעֱשֶׂ֔ה לְ/ב֥וּל עֵ֖ץ אֶסְגּֽוֹד", "en": {"kjv": "And none considereth in his heart, neither is there knowledge nor understanding to say, I have burned part of it in the fire; yea, also I have baked bread upon the coals thereof; I have roasted flesh, and eaten it: and shall I make the residue thereof an abomination? shall I fall down to the stock of a tree?", "web": "No one thinks, neither is there knowledge nor understanding to say, “I have burned part of it in the fire. Yes, I have also baked bread on its coals. I have roasted meat and eaten it. Shall I make the rest of it into an abomination? Shall I bow down to a tree trunk?”", "bsb": "And no one considers in his heart, no one has the knowledge or insight to say, “I burned half of it in the fire, and I baked bread on its coals; I roasted meat and I ate. Shall I make something detestable with the rest of it? Shall I bow down to a block of wood?”", "asv": "And none calleth to mind, neither is there knowledge nor understanding to say, I have burned part of it in the fire; yea, also I have baked bread upon the coals thereof; I have roasted flesh and eaten it: and shall I make the residue thereof an abomination? shall I fall down to the stock of a tree?", "ylt": "And none doth turn it back unto his heart, Nor hath knowledge nor understanding to say, `Half of it I have burned in the fire, Yea, also, I have baked bread over its coals, I roast flesh and I eat, And its remnant for an abomination I make, To the stock of a tree I fall down.'", "dra": "They do not consider in their mind, nor know, nor have the thought to say: I have burnt part of it in the fire, and I have baked bread upon the coals thereof: I have broiled flesh and have eaten, and of the residue thereof shall I make an idol? shall I fall down before the stock of a tree?", "bbe": "And no one takes note, no one has enough knowledge or wisdom to say, I have put part of it in the fire, and made bread on it; I have had a meal of the flesh cooked with it: and am I now to make the rest of it into a false god? am I to go down on my face before a bit of wood?", "geneva": "And none considereth in his heart, neither is there knowledge nor vnderstanding to say, I haue burnt halfe of it, euen in the fire, and haue baked bread also vpon the coles thereof: I haue rosted flesh, and eaten it, and shall I make the residue thereof an abomination? shall I bowe to the stocke of a tree?", "wycliffe": "Thei bythenken not in her soule, nether thei knowen, nether thei feelen, that thei seie, Y brente the myddil therof in fier, and Y bakide looues on the coolis therof, and Y sethide fleischis, and eet; and of the residue therof schal Y make an idol? schal Y falle doun bifore the stok of a tree?", "rotherham": "And no one reflecteth—There is neither knowledge nor discernment—to say, Half thereof, have I burned up in the fire Moreover also I have baked, on the coals thereof, bread, I roasted flesh, and have been eating,—And of the remainder thereof, an abomination, shall I make? And, to a log of wood, shall I pay adoration?", "darby": "And none taketh it to heart, neither is there knowledge nor understanding to say, I have burned part of it in the fire, and have also baked bread upon the coals thereof, I have roasted flesh, and eaten [it], and with the rest thereof shall I make an abomination? shall I bow down to a block of wood?", "twenty": "", "jps": "And none considereth in his heart, neither is there knowledge nor understanding to say: 'I have burned the half of it in the fire; yea, also I have baked bread upon the coals thereof; I have roasted flesh and eaten it; and shall I make the residue thereof an abomination? Shall I fall down to the stock of a tree?'", "acv": "And none calls to mind, nor is there knowledge nor understanding to say, I have burned part of it in the fire. Yea, I have also baked bread upon the coals of it. I have roasted flesh and eaten it. And shall I make the residue of it an abomination? Shall I fall down to the stock of a tree?", "anderson": "", "haweis": "", "noyes": "None considereth in his mind, Or hath knowledge and understanding to say: \"Half of it I have burned with fire; I have also baked bread on the coals of it; I have roasted flesh and have eaten; And shall I make the remnant an abomination? Shall I fall down before the stock of a tree?\"", "webster": "And none considereth in his heart, neither [is there] knowledge nor understanding to say, I have burned part of it in the fire; I have also baked bread upon its coals; I have roasted flesh, and eaten [it]: and shall I make the residue of it an abomination? shall I fall down to the stock of a tree?", "vulgate": "non recogitant in mente sua neque cognoscunt neque sentiunt ut dicant medietatem eius conbusi igne et coxi super carbones eius panes coxi carnes et comedi et de reliquo eius idolum faciam ante truncum ligni procidam;", "brenton": "And one has not considered in his mind, nor known in his understanding, that he has burnt up half of it in the fire, and baked loaves on the coals thereof and has roasted and eaten flesh, and of the rest of it he has made an abomination, and they worship it."}}, {"v": 20, "ref": "44:20", "o": "רֹעֶ֣ה אֵ֔פֶר לֵ֥ב הוּתַ֖ל הִטָּ֑/הוּ וְ/לֹֽא יַצִּ֤יל אֶת נַפְשׁ/וֹ֙ וְ/לֹ֣א יֹאמַ֔ר הֲ/ל֥וֹא שֶׁ֖קֶר בִּ/ימִינִֽ/י", "en": {"kjv": "He feedeth on ashes: a deceived heart hath turned him aside, that he cannot deliver his soul, nor say, Is there not a lie in my right hand?", "web": "He feeds on ashes. A deceived heart has turned him aside; and he can’t deliver his soul, nor say, “Isn’t there a lie in my right hand?”", "bsb": "He feeds on ashes. His deluded heart has led him astray, and he cannot deliver himself or say, “Is not this thing in my right hand a lie?”", "asv": "He feedeth on ashes; a deceived heart hath turned him aside; and he cannot deliver his soul, nor say, Is there not a lie in my right hand?", "ylt": "Feeding on ashes, the heart is deceived, It hath turned him aside, And he delivereth not his soul, nor saith: `Is there not a lie in my right hand?'", "dra": "Part thereof is ashes: his foolish heart adoreth it, and he will not save his soul, nor say: Perhaps there is a lie in my right hand.", "bbe": "As for him whose food is the dust of a dead fire, he has been turned from the way by a twisted mind, so that he is unable to keep himself safe by saying, What I have here in my hand is false.", "geneva": "He feedeth of ashes: a seduced heart hath deceiued him, that he cannot deliuer his soule, nor say, Is there not a lye in my right hand?", "wycliffe": "A part therof is aische; an vnwijs herte schal worschipe it, and he schal not delyuere his soule, nether he schal seie, A strong leesyng is in my riythond.", "rotherham": "He is feeding on ashes, A deluded heart, hath turned him aside,—And he cannot deliver his own soul nor say, Is there not a falsehood in my right hand?", "darby": "He feedeth on ashes; a deceived heart hath turned him aside, that he cannot deliver his soul, nor say, Is there not a lie in my right hand?", "twenty": "", "jps": "He striveth after ashes, a deceived heart hath turned him aside, that he cannot deliver his soul, nor say: 'Is there not a lie in my right hand?'", "acv": "He feeds on ashes. A deceived heart has turned him aside. And he cannot deliver his soul, nor say, Is there not a lie in my right hand?", "anderson": "", "haweis": "", "noyes": "He toileth for ashes; A deluded heart turneth him aside, So that he cannot deliver himself, and say \"Is there not a lie in my right hand?\"", "webster": "He feedeth on ashes: a deceived heart hath turned him aside, that he cannot deliver his soul, nor say, [Is there] not a lie in my right hand?", "vulgate": "pars eius cinis est cor insipiens adoravit illud et non liberabit animam suam neque dicet forte mendacium est in dextera mea;", "brenton": "Know thou that their heart is ashes, and they err, and no one is able to deliver his soul: see, ye will not say, There is a lie in my right hand."}}, {"v": 21, "ref": "44:21", "o": "זְכָר אֵ֣לֶּה יַעֲקֹ֔ב וְ/יִשְׂרָאֵ֖ל כִּ֣י עַבְדִּ/י אָ֑תָּה יְצַרְתִּ֤י/ךָ עֶֽבֶד לִ/י֙ אַ֔תָּה יִשְׂרָאֵ֖ל לֹ֥א תִנָּשֵֽׁ/נִי", "en": {"kjv": "Remember these, O Jacob and Israel; for thou art my servant: I have formed thee; thou art my servant: O Israel, thou shalt not be forgotten of me.", "web": "Remember these things, Jacob and Israel; for you are my servant. I have formed you. You are my servant. Israel, you will not be forgotten by me.", "bsb": "Remember these things, O Jacob, for you are My servant, O Israel. I have made you, and you are My servant; O Israel, I will never forget you.", "asv": "Remember these things, O Jacob, and Israel; for thou art my servant: I have formed thee; thou art my servant: O Israel, thou shalt not be forgotten of me.", "ylt": "Remember these, O Jacob, and Israel, For My servant thou art , I formed thee, a servant to Me thou art , O Israel, thou dost not forget Me.", "dra": "Remember these things, O Jacob, and Israel, for thou art my servant. I have formed thee, thou art my servant, O Israel, forget me not.", "bbe": "Keep these things in mind, O Jacob; and you Israel, for you are my servant: I have made you; you are my servant; O Israel, I will not let you go out of my memory.", "geneva": "Remember these (O Iaakob and Israel) for thou art my seruant: I haue formed thee: thou art my seruant: O Israel forget me not.", "wycliffe": "Thou, Jacob, and Israel, haue mynde of these thingis, for thou art my seruaunt; Y formyde thee, Israel, thou art my seruaunt; thou schalt not foryete me.", "rotherham": "Remember these things, O Jacob, And, Israel,—for, my Servant, thou art,—I have fashioned thee, a Servant of mine, thou art.", "darby": "Remember these things, O Jacob, and Israel, for thou art my servant; I have formed thee: thou art my servant, Israel; thou shalt not be forgotten of me.", "twenty": "", "jps": "Remember these things, O Jacob, and Israel, for thou art My servant; I have formed thee, thou art Mine own servant; O Israel, thou shouldest not forget Me.", "acv": "Remember these things, O Jacob, and Israel, for thou are my servant. I have formed thee. Thou are my servant, O Israel, thou shall not be forgotten by me.", "anderson": "", "haweis": "", "noyes": "Remember these things, O Jacob, O Israel, for thou art my servant! I formed thee; thou art my servant; O Israel, I will not forget thee.", "webster": "Remember these, O Jacob and Israel; for thou [art] my servant: I have formed thee; thou [art] my servant: O Israel, thou shalt not be forgotten by me.", "vulgate": "memento horum Iacob et Israhel quoniam servus meus es tu formavi te servus meus es tu Israhel non oblivisceris mei;", "brenton": "Remember these things, O Jacob and Israel; for thou art my servant; I have formed thee to be my servant: and do thou, Israel, not forget me."}}, {"v": 22, "ref": "44:22", "o": "מָחִ֤יתִי כָ/עָב֙ פְּשָׁעֶ֔י/ךָ וְ/כֶ/עָנָ֖ן חַטֹּאותֶ֑י/ךָ שׁוּבָ֥/ה אֵלַ֖/י כִּ֥י גְאַלְתִּֽי/ךָ", "en": {"kjv": "I have blotted out, as a thick cloud, thy transgressions, and, as a cloud, thy sins: return unto me; for I have redeemed thee.", "web": "I have blotted out, as a thick cloud, your transgressions, and, as a cloud, your sins. Return to me, for I have redeemed you.", "bsb": "I have blotted out your transgressions like a cloud, and your sins like a mist. Return to Me, for I have redeemed you.", "asv": "I have blotted out, as a thick cloud, thy transgressions, and, as a cloud, thy sins: return unto me; for I have redeemed thee.", "ylt": "I have blotted out, as by a thick cloud, Thy transgressions, And as by a cloud thy sins, Return unto Me, for I have redeemed thee.", "dra": "I have blotted out thy iniquities as a cloud, and thy sins as a mist: return to me, for I have redeemed thee.", "bbe": "I have put your evil doings out of my mind like a thick cloud, and your sins like a mist: come back to me; for I have taken up your cause.", "geneva": "I haue put away thy transgressions like a cloude, and thy sinnes, as a mist: turne vnto me, for I haue redeemed thee.", "wycliffe": "Y dide awei thi wickidnessis as a cloude, and thi synnes as a myist; turne thou ayen to me, for Y ayenbouyte thee.", "rotherham": "O Israel, thou shalt not be forgotten of me, I have wiped out, As with a thick cloud, thy transgressions, And as with a broad cloud, thy sins,—Return unto me, for I have redeemed thee.", "darby": "I have blotted out, as a thick cloud, thy transgressions, and, as a cloud, thy sins: return unto me; for I have redeemed thee.", "twenty": "", "jps": "I have blotted out, as a thick cloud, thy transgressions, and, as a cloud, thy sins; return unto Me, for I have redeemed thee.", "acv": "I have blotted out, as a thick cloud, thy transgressions, and, as a cloud, thy sins. Return to me, for I have redeemed thee.", "anderson": "", "haweis": "", "noyes": "I have caused thy transgressions to vanish like a cloud, And thy sins like a mist; Return to me, for I have redeemed thee!", "webster": "I have blotted out, as a thick cloud, thy transgressions, and as a cloud, thy sins: return to me; for I have redeemed thee.", "vulgate": "delevi ut nubem iniquitates tuas et quasi nebulam peccata tua revertere ad me quoniam redemi te;", "brenton": "For behold, I have blotted out as a cloud thy transgressions, and thy sin as darkness: turn to me, and I will redeem thee."}}, {"v": 23, "ref": "44:23", "o": "רָנּ֨וּ שָׁמַ֜יִם כִּֽי עָשָׂ֣ה יְהוָ֗ה הָרִ֨יעוּ֙ תַּחְתִּיּ֣וֹת אָ֔רֶץ פִּצְח֤וּ הָרִים֙ רִנָּ֔ה יַ֖עַר וְ/כָל עֵ֣ץ בּ֑/וֹ כִּֽי גָאַ֤ל יְהוָה֙ יַֽעֲקֹ֔ב וּ/בְ/יִשְׂרָאֵ֖ל יִתְפָּאָֽר", "en": {"kjv": "Sing, O ye heavens; for the Lord hath done it: shout, ye lower parts of the earth: break forth into singing, ye mountains, O forest, and every tree therein: for the Lord hath redeemed Jacob, and glorified himself in Israel.", "web": "Sing, you heavens, for Yahweh has done it! Shout, you lower parts of the earth! Break out into singing, you mountains, O forest, all of your trees, for Yahweh has redeemed Jacob, and will glorify himself in Israel.", "bsb": "Sing for joy, O heavens, for the LORD has done this; shout aloud, O depths of the earth. Break forth in song, O mountains, you forests and all your trees. For the LORD has redeemed Jacob, and revealed His glory in Israel.", "asv": "Sing, O ye heavens, for Jehovah hath done it; shout, ye lower parts of the earth; break forth into singing, ye mountains, O forest, and every tree therein: for Jehovah hath redeemed Jacob, and will glorify himself in Israel.", "ylt": "Sing, O heavens, for Jehovah hath wrought, Shout, O lower parts of earth, Break forth, O mountains, with singing, Forest, and every tree in it, For Jehovah hath redeemed Jacob, And in Israel He doth beautify Himself.", "dra": "Give praise, O ye heavens, for the Lord hath shewn mercy: shout with joy, ye ends of the earth: ye mountains, resound with praise, thou, O forest, and every tree therein: for the Lord hath redeemed Jacob, and Israel shall be glorified.", "bbe": "Make a song, O heavens, for the Lord has done it: give a loud cry, you deep parts of the earth: let your voices be loud in song, you mountains, and you woods with all your trees: for the Lord has taken up the cause of Jacob, and will let his glory be seen in Israel.", "geneva": "Reioyce, ye heauens: for the Lord hath done it: shoute, ye lower partes of the earth: brast foorth into prayses, ye mountaines, O forest and euery tree therein: for the Lord hath redeemed Iaakob and will be glorified in Israel.", "wycliffe": "Ye heuenes, herie, for the Lord hath do merci; the laste partis of erth, synge ye hertli song; hillis, sowne ye preisyng; the forest and ech tre therof, herie God; for the Lord ayenbouyte Jacob, and Israel schal haue glorie.", "rotherham": "Shout in triumph ye heavens for Yahweh, hath effectually wrought. Shout, O ye underparts of the earth, Ring out, Ye mountains, into cries of triumph, Thou forest, and every tree therein,—For, Yahweh, hath redeemed, Jacob, And in Israel, will he get himself glory.", "darby": "Sing, ye heavens; for Jehovah hath done it: shout, ye lower parts of the earth; break forth into singing, ye mountains, the forest, and every tree therein! For Jehovah hath redeemed Jacob, and glorified himself in Israel.", "twenty": "", "jps": "Sing, O ye heavens, for HaShem hath done it; shout, ye lowest parts of the earth; break forth into singing, ye mountains, O forest, and every tree therein; for HaShem hath redeemed Jacob, and doth glorify Himself in Israel.", "acv": "Sing, O ye heavens, for Jehovah has done it. Shout, ye lower parts of the earth. Break forth into singing, ye mountains, O forest, and every tree therein. For Jehovah has redeemed Jacob, and will glorify himself in Israel.", "anderson": "", "haweis": "", "noyes": "Sing, O ye heavens, for Jehovah hath done it; Shout, O ye depths of the earth! Break forth into song, ye mountains! Thou forest, and every tree therein! For Jehovah hath redeemed Jacob, And glorified himself in Israel.", "webster": "Sing, O ye heavens; for the LORD hath done [it]: shout, ye lower parts of the earth: break forth into singing, ye mountains, O forest, and every tree therein: for the LORD hath redeemed Jacob, and glorified himself in Israel.", "vulgate": "laudate caeli quoniam fecit Dominus iubilate extrema terrae resonate montes laudationem saltus et omne lignum eius quoniam redemit Dominus Iacob et Israhel gloriabitur;", "brenton": "Rejoice, ye heavens; for God has had mercy upon Israel: sound the trumpet, ye foundations of the earth: ye mountains, shout with joy, ye hills, and all the trees therein: for God has redeemed Jacob, and Israel shall be glorified."}}, {"v": 24, "ref": "44:24", "o": "כֹּֽה אָמַ֤ר יְהוָה֙ גֹּאֲלֶ֔/ךָ וְ/יֹצֶרְ/ךָ֖ מִ/בָּ֑טֶן אָנֹכִ֤י יְהוָה֙ עֹ֣שֶׂה כֹּ֔ל נֹטֶ֤ה שָׁמַ֨יִם֙ לְ/בַדִּ֔/י רֹקַ֥ע הָ/אָ֖רֶץ מי את/י מֵ/אִתִּֽ/י", "en": {"kjv": "Thus saith the Lord, thy redeemer, and he that formed thee from the womb, I am the Lord that maketh all things; that stretcheth forth the heavens alone; that spreadeth abroad the earth by myself;", "web": "Thus says Yahweh, your Redeemer, and he who formed you from the womb: “I am Yahweh, who makes all things; who alone stretches out the heavens; who spreads out the earth by myself;", "bsb": "Thus says the LORD, your Redeemer who formed you from the womb: “I am the LORD, who has made all things, who alone stretched out the heavens, who by Myself spread out the earth,", "asv": "Thus saith Jehovah, thy Redeemer, and he that formed thee from the womb: I am Jehovah, that maketh all things; that stretcheth forth the heavens alone; that spreadeth abroad the earth (who is with me?);", "ylt": "Thus said Jehovah, thy redeemer, And thy framer from the womb: `I am Jehovah, doing all things, Stretching out the heavens by Myself, Spreading out the earth--who is with Me?", "dra": "Thus saith the Lord thy redeemer, and thy maker, from the womb: I am the Lord, that make all things, that alone stretch out the heavens, that established the earth, and there is none with me.", "bbe": "The Lord, who has taken up your cause, and who gave you life in your mother's body, says, I am the Lord who makes all things; stretching out the heavens by myself, and giving the earth its limits; who was with me?", "geneva": "Thus sayeth the Lord thy redeemer and he that formed thee from the wombe, I am the Lord, that made all things, that spred out the heauens alone, and stretched out the earth by my selfe.", "wycliffe": "The Lord, thin ayenbiere, and thi fourmere fro the wombe, seith these thingis, Y am the Lord, makynge alle thingis, and Y aloone stretche forth heuenes, and stablische the erthe, and noon is with me;", "rotherham": "Thus, saith Yahweh Who hath redeemed thee, Who hath fashioned thee from birth,—I—Yahweh, am the maker of all things, Stretching out the heavens, alone, Spreading forth the earth, of myself;", "darby": "Thus saith Jehovah, thy Redeemer, and he that formed thee from the womb: I [am] Jehovah, the maker of all things; who alone stretched out the heavens, who did spread forth the earth by myself;", "twenty": "", "jps": "Thus saith HaShem, thy Redeemer, and He that formed thee from the womb: I am HaShem, that maketh all things; that stretched forth the heavens alone; that spread abroad the earth by Myself;", "acv": "Thus says Jehovah, thy Redeemer, and he who formed thee from the womb: I am Jehovah, who makes all things, who stretches forth the heavens alone, who spreads abroad the earth (who is with me?),", "anderson": "", "haweis": "", "noyes": "Thus saith Jehovah, thy Redeemer, Even he that formed thee from the womb; I am Jehovah, who made all things; Who stretched out the heavens alone; Who spread out the earth by myself;", "webster": "Thus saith the LORD thy Redeemer, and he that formed thee from the womb, [I am] the LORD that maketh all [things]; that stretcheth forth the heavens alone; that spreadeth abroad the earth by myself:", "vulgate": "haec dicit Dominus redemptor tuus et formator tuus ex utero ego sum Dominus faciens omnia extendens caelos solus stabiliens terram et nullus mecum;", "brenton": "Thus saith the Lord that redeems thee, and who formed thee from the womb, I am the Lord that performs all things: I stretched out the heaven alone, and established the earth."}}, {"v": 25, "ref": "44:25", "o": "מֵפֵר֙ אֹת֣וֹת בַּדִּ֔ים וְ/קֹסְמִ֖ים יְהוֹלֵ֑ל מֵשִׁ֧יב חֲכָמִ֛ים אָח֖וֹר וְ/דַעְתָּ֥/ם יְשַׂכֵּֽל", "en": {"kjv": "That frustrateth the tokens of the liars, and maketh diviners mad; that turneth wise men backward, and maketh their knowledge foolish;", "web": "who frustrates the signs of the liars, and makes diviners mad; who turns wise men backward, and makes their knowledge foolish;", "bsb": "who foils the signs of false prophets and makes fools of diviners, who confounds the wise and turns their knowledge into nonsense,", "asv": "that frustrateth the signs of the liars, and maketh diviners mad; that turneth wise men backward, and maketh their knowledge foolish;", "ylt": "Making void the tokens of devisers, And diviners it maketh mad, Turning the wise backward, And their knowledge it maketh foolish.", "dra": "That make void the tokens of diviners, and make the soothsayers mad. That turn the wise backward, and that make their knowledge foolish.", "bbe": "Who makes the signs of those who give word of the future come to nothing, so that those who have knowledge of secret arts go off their heads; turning the wise men back, and making their knowledge foolish:", "geneva": "I destroy the tokens of ye southsayers, and make them that coniecture, fooles, and turne the wise men backwarde, and make their knowledge foolishnesse.", "wycliffe": "and Y make voide the signes of false dyuynours, and Y turne in to woodnesse dyuynours, that dyuynen by sacrifices offrid to feendis; and Y turne wise men bacward, and Y make her science fonned.", "rotherham": "Frustrating the signs of praters, And, diviners, he confoundeth,—Turning wise men backwards, And their knowledge, he maketh folly;", "darby": "— he that frustrateth the tokens of the liars, and maketh diviners mad; that turneth wise men backward, and maketh their knowledge foolish;", "twenty": "", "jps": "That frustrateth the tokens of the imposters, and maketh diviners mad; that turneth wise men backward, and maketh their knowledge foolish;", "acv": "who frustrates the signs of the liars, and makes diviners mad, who turns wise men backward, and makes their knowledge foolish,", "anderson": "", "haweis": "", "noyes": "Who frustrateth the signs of deceivers, And maketh the diviners mad; Who putteth the wise men to shame, And maketh their knowledge folly;", "webster": "That frustrateth the tokens of the liars, and maketh diviners mad; that turneth wise [men] backward, and maketh their knowledge foolish;", "vulgate": "irrita faciens signa divinorum et ariolos in furorem vertens convertens sapientes retrorsum et scientiam eorum stultam faciens;", "brenton": "Who else will frustrate the tokens of those that have divining spirits, and prophecies from the heart of man? turning the wise back, and making their counsel foolishness;"}}, {"v": 26, "ref": "44:26", "o": "מֵקִים֙ דְּבַ֣ר עַבְדּ֔/וֹ וַ/עֲצַ֥ת מַלְאָכָ֖י/ו יַשְׁלִ֑ים הָ/אֹמֵ֨ר לִ/ירוּשָׁלִַ֜ם תּוּשָׁ֗ב וּ/לְ/עָרֵ֤י יְהוּדָה֙ תִּבָּנֶ֔ינָה וְ/חָרְבוֹתֶ֖י/הָ אֲקוֹמֵֽם", "en": {"kjv": "That confirmeth the word of his servant, and performeth the counsel of his messengers; that saith to Jerusalem, Thou shalt be inhabited; and to the cities of Judah, Ye shall be built, and I will raise up the decayed places thereof:", "web": "who confirms the word of his servant, and performs the counsel of his messengers; who says of Jerusalem, ‘She will be inhabited;’ and of the cities of Judah, ‘They will be built,’ and ‘I will raise up its waste places;’", "bsb": "who confirms the message of His servant and fulfills the counsel of His messengers, who says of Jerusalem, ‘She will be inhabited,’ and of the cities of Judah, ‘They will be rebuilt, and I will restore their ruins,’", "asv": "that confirmeth the word of his servant, and performeth the counsel of his messengers; that saith of Jerusalem, She shall be inhabited; and of the cities of Judah, They shall be built, and I will raise up the waste places thereof;", "ylt": "Confirming the word of His servant, The counsel of His messengers it perfecteth, Who is saying of Jerusalem, She is inhabited, And of cities of Judah, They shall be built, and her wastes I raise up,", "dra": "That raise up the word of my servant and perform the counsel of my messengers, who say to Jerusalem: Thou shalt be inhabited: and to the cities of Juda: You shall be built, and I will raise up the wastes thereof.", "bbe": "Who makes the word of his servants certain, and gives effect to the purposes of his representatives; who says of Jerusalem, Her people will come back to her; and of the towns of Judah, I will give orders for their building, and will make her waste places fertile again:", "geneva": "He confirmeth the worde of his seruant and performeth the counsell of his messengers, saying to Ierusalem, Thou shalt bee inhabited: and to the cities of Iudah, Yee shall be built vp, and I will repayre the decayed places thereof.", "wycliffe": "And the Lord reisith the word of his seruaunt, and fillith the councel of hise messangeris; and Y seie, Jerusalem, thou schalt be enhabitid; and to the citees of Juda, Ye schulen be bildid, and Y schal reise the desertis therof;", "rotherham": "Establishing the word of his Servant, And the counsel of his Messengers, he maketh good,—Who saith of Jerusalem—She shall be inhabited! And of the cities of Judah—They shall be built! And the ruins thereof, will I set up!", "darby": "that confirmeth the word of his servant, and performeth the counsel of his messengers; that saith to Jerusalem, Thou shalt be inhabited; and to the cities of Judah, Ye shall be built up, and I will raise up their ruins;", "twenty": "", "jps": "That confirmeth the word of His servant, and performeth the counsel of His messengers; that saith of Jerusalem: 'She shall be inhabited'; and of the cities of Judah: 'They shall be built, and I will raise up the waste places thereof';", "acv": "who confirms the word of his servant, and performs the counsel of his messengers, who says of Jerusalem, She shall be inhabited, and of the cities of Judah, They shall be built, and I will raise up the waste places of it,", "anderson": "", "haweis": "", "noyes": "Who establisheth the word of his servant, And performeth the purpose of his messengers; Who saith of Jerusalem, \"She shall be inhabited,\" And of the cities of Judah, \"They shall be built,\" And, \"Her desolated places I will restore.\"", "webster": "That confirmeth the word of his servant, and performeth the counsel of his messengers; that saith to Jerusalem, Thou shalt be inhabited; and to the cities of Judah, Ye shall be built, and I will raise up her decayed places:", "vulgate": "suscitans verbum servi sui et consilium nuntiorum suorum conplens qui dico Hierusalem habitaberis et civitatibus Iuda aedificabimini et deserta eius suscitabo;", "brenton": "and confirming the word of his servant, and verifying the counsel of his messengers: who says to Jerusalem, Thou shalt be inhabited; and to the cities of Idumea, Ye shall be built, and her desert places shall spring forth."}}, {"v": 27, "ref": "44:27", "o": "הָ/אֹמֵ֥ר לַ/צּוּלָ֖ה חֳרָ֑בִי וְ/נַהֲרֹתַ֖יִ/ךְ אוֹבִֽישׁ", "en": {"kjv": "That saith to the deep, Be dry, and I will dry up thy rivers:", "web": "who says to the deep, ‘Be dry,’ and ‘I will dry up your rivers;’", "bsb": "who says to the depths of the sea, ‘Be dry, and I will dry up your currents,’", "asv": "that saith to the deep, Be dry, and I will dry up thy rivers;", "ylt": "Who is saying to the deep, Be dry, and thy rivers I cause to dry up,", "dra": "Who say to the deep: Be thou desolate, and I will dry up thy rivers.", "bbe": "Who says to the deep, Be dry, and I will make your rivers dry:", "geneva": "He saith to the deepe, Be drye and I will drye vp thy floods.", "wycliffe": "and Y seie to the depthe, Be thou desolat, and Y shal make drie thi floodis;", "rotherham": "Who saith to the deep—Be dry and Thy rivers, will I drain!", "darby": "that saith to the deep, Be dry, and I will dry up thy rivers;", "twenty": "", "jps": "That saith to the deep: 'Be dry, and I will dry up thy rivers';", "acv": "who says to the deep, Be dry, and I will dry up thy rivers,", "anderson": "", "haweis": "", "noyes": "Who saith to the deep, \"Be dry! I will dry up thy streams!\"", "webster": "That saith to the deep, Be dry, and I will dry up thy rivers:", "vulgate": "qui dico profundo desolare et flumina tua arefaciam;", "brenton": "Who says to the deep, Thou shalt be dried up, and I will dry up the rivers."}}, {"v": 28, "ref": "44:28", "o": "הָ/אֹמֵ֤ר לְ/כ֨וֹרֶשׁ֙ רֹעִ֔/י וְ/כָל חֶפְצִ֖/י יַשְׁלִ֑ם וְ/לֵ/אמֹ֤ר לִ/ירוּשָׁלִַ֨ם֙ תִּבָּנֶ֔ה וְ/הֵיכָ֖ל תִּוָּסֵֽד", "en": {"kjv": "That saith of Cyrus, He is my shepherd, and shall perform all my pleasure: even saying to Jerusalem, Thou shalt be built; and to the temple, Thy foundation shall be laid.", "web": "Who says of Cyrus, ‘He is my shepherd, and shall perform all my pleasure,’ even saying of Jerusalem, ‘She will be built;’ and of the temple, ‘Your foundation will be laid.’”", "bsb": "who says of Cyrus, ‘My shepherd will fulfill all that I desire,’ who says of Jerusalem, ‘She will be rebuilt,’ and of the temple, ‘Let its foundation be laid.’”", "asv": "That saith of Cyrus, He is my shepherd, and shall perform all my pleasure, even saying of Jerusalem, She shall be built; and of the temple, Thy foundation shall be laid.", "ylt": "Who is saying of Cyrus, My shepherd, And all my delight He doth perfect, So as to say of Jerusalem, Thou art built, And of the temple, Thou art founded.", "dra": "Who say to Cyrus: Thou art my shepherd, and thou shalt perform all my pleasure. Who say to Jerusalem: Thou shalt be built: and to the temple: Thy foundations shall be laid.", "bbe": "Who says of Cyrus, He will take care of my sheep, and will do all my pleasure: who says of Jerusalem, I will give the word for your building; and of the Temple, Your bases will be put in place.", "geneva": "He saith to Cyrus, Thou art my shepheard: and he shall performe all my desire: saying also to Ierusalem, Thou shalt be built: and to the Temple, Thy foundation shall be surely layed.", "wycliffe": "and Y seie to Cirus, Thou art my scheepherde, and thou schalt fille al my wille; and Y seie to Jerusalem, Thou schalt be bildid; and to the temple, Thou schalt be foundid.", "rotherham": "Who saith of Cyrus—My Shepherd! and All my pleasure, shall he make good Even saying of Jerusalem—She shall be built! And of the temple—Be her foundation laid!", "darby": "that saith of Cyrus, [He is] my shepherd, and he shall perform all my pleasure; even saying to Jerusalem, Thou shalt be built; and to the temple, Thy foundation shall be laid.", "twenty": "", "jps": "That saith of Cyrus: 'He is My shepherd, and shall perform all My pleasure'; even saying of Jerusalem: 'She shall be built'; and to the temple: 'My foundation shall be laid.'", "acv": "who says of Cyrus, He is my shepherd, and shall perform all my pleasure, even saying of Jerusalem, She shall be built, and of the temple, Thy foundation shall be laid.", "anderson": "", "haweis": "", "noyes": "Who saith of Cyrus, \"He is my shepherd; He shall perform all my pleasure\"; Who saith of Jerusalem, \"She shall be built,\" And of the temple, \"Her foundation shall be laid.\"", "webster": "That saith of Cyrus, [He is] my shepherd, and [he] shall perform all my pleasure: even saying to Jerusalem, Thou shalt be built; and to the temple, Thy foundation shall be laid.", "vulgate": "qui dico Cyro pastor meus es et omnem voluntatem meam conplebis qui dico Hierusalem aedificaberis et templo fundaberis;", "brenton": "Who bids Cyrus be wise, and he shall perform all my will: who says to Jerusalem, Thou shalt be built, and I will lay the foundation of my holy house."}}]}, {"c": 45, "verses": [{"v": 1, "ref": "45:1", "o": "כֹּה אָמַ֣ר יְהוָה֮ לִ/מְשִׁיח/וֹ֮ לְ/כ֣וֹרֶשׁ אֲשֶׁר הֶחֱזַ֣קְתִּי בִֽ/ימִינ֗/וֹ לְ/רַד לְ/פָנָי/ו֙ גּוֹיִ֔ם וּ/מָתְנֵ֥י מְלָכִ֖ים אֲפַתֵּ֑חַ לִ/פְתֹּ֤חַ לְ/פָנָי/ו֙ דְּלָתַ֔יִם וּ/שְׁעָרִ֖ים לֹ֥א יִסָּגֵֽרוּ", "en": {"kjv": "Thus saith the Lord to his anointed, to Cyrus, whose right hand I have holden, to subdue nations before him; and I will loose the loins of kings, to open before him the two leaved gates; and the gates shall not be shut;", "web": "Thus says Yahweh to his anointed, to Cyrus, whose right hand I have held, to subdue nations before him, and strip kings of their armor; to open the doors before him, and the gates shall not be shut:", "bsb": "This is what the LORD says to Cyrus His anointed, whose right hand I have grasped to subdue nations before him, to disarm kings, to open the doors before him, so that the gates will not be shut:", "asv": "Thus saith Jehovah to his anointed, to Cyrus, whose right hand I have holden, to subdue nations before him, and I will loose the loins of kings; to open the doors before him, and the gates shall not be shut:", "ylt": "Thus said Jehovah, To His anointed, to Cyrus, Whose right hand I have laid hold on, To subdue nations before him, Yea, loins of kings I loose, To open before him two-leaved doors, Yea, gates are not shut:", "dra": "Thus saith the Lord to my anointed Cyrus, whose right hand I have taken hold of, to subdue nations before his face, and to turn the backs of kings, and to open the doors before him, and the gates shall not be shut.", "bbe": "The Lord says to the man of his selection, to Cyrus, whom I have taken by the right hand, putting down nations before him, and taking away the arms of kings; making the doors open before him, so that the ways into the towns may not be shut;", "geneva": "Thus sayeth the Lord vnto Cyrus his anointed, whose right hand I haue holden to subdue nations before him: therefore will I weaken the loynes of Kings and open the doores before him, and the gates shall not be shut:", "wycliffe": "The Lord seith these thingis to my crist, Cirus, whos riythond Y took, that Y make suget folkis bifor his face, and turne the backis of kyngis; and Y schal opene yatis bifore hym, and yatis schulen not be closid.", "rotherham": "Thus, saith Yahweh, to his Anointed, to Cyrus—Whose right hand I have firmly grasped To subdue before him, nations, And the loins of kings, will I ungird,—To open, before him, the two-leaved doors, And, the gates, shall not be shut:", "darby": "Thus saith Jehovah to his anointed, to Cyrus, whose right hand I have holden, to subdue nations before him — and I will loose the loins of kings; to open before him the two-leaved doors, and the gates shall not be shut:", "twenty": "", "jps": "Thus saith HaShem to His anointed, to Cyrus, whose right hand I have holden, to subdue nations before him, and to loose the loins of kings; to open the doors before him, and that the gates may not be shut:", "acv": "Thus says Jehovah to his anointed, to Cyrus, whose right hand I have held to subdue nations before him. And I will loose the loins of kings to open the doors before him. And the gates shall not be shut.", "anderson": "", "haweis": "", "noyes": "Thus saith Jehovah to his anointed, To Cyrus, whom I hold by his right hand, To subdue nations before him, And ungird the loins of kings; To open before him the two-leaved gates, And the doors shall not be shut.", "webster": "Thus saith the LORD to his anointed, to Cyrus, whose right hand I have held to subdue nations before him; and I will loose the loins of kings, to open before him the two-leaved gates, and the gates shall not be shut;", "vulgate": "haec dicit Dominus christo meo Cyro cuius adprehendi dexteram ut subiciam ante faciem eius gentes et dorsa regum vertam et aperiam coram eo ianuas et portae non cludentur;", "brenton": "Thus saith the Lord God to my anointed Cyrus, whose right hand I have held, that nations might be obedient before him; and I will break through the strength of kings; I will open doors before him, and cities shall not be closed."}}, {"v": 2, "ref": "45:2", "o": "אֲנִי֙ לְ/פָנֶ֣י/ךָ אֵלֵ֔ךְ וַ/הֲדוּרִ֖ים אושר אֲיַשֵּׁ֑ר דַּלְת֤וֹת נְחוּשָׁה֙ אֲשַׁבֵּ֔ר וּ/בְרִיחֵ֥י בַרְזֶ֖ל אֲגַדֵּֽעַ", "en": {"kjv": "I will go before thee, and make the crooked places straight: I will break in pieces the gates of brass, and cut in sunder the bars of iron:", "web": "“I will go before you, and make the rough places smooth. I will break the doors of brass in pieces, and cut apart the bars of iron.", "bsb": "“I will go before you and level the mountains; I will break down the gates of bronze and cut through the bars of iron.", "asv": "I will go before thee, and make the rough places smooth; I will break in pieces the doors of brass, and cut in sunder the bars of iron;", "ylt": "`I go before thee, and crooked places make straight, Two-leaved doors of brass I shiver, And bars of iron I cut asunder,", "dra": "I will go before thee, and will humble the great ones of the earth: I will break in pieces the gates of brass, and will burst the bars of iron.", "bbe": "I will go before you, and make the rough places level: the doors of brass will be broken, and the iron rods cut in two:", "geneva": "I will goe before thee and make the crooked streight: I will breake the brasen doores, and burst the yron barres.", "wycliffe": "Y schal go bifore thee, and Y schal make lowe the gloriouse men of erthe; Y schal al to-breke brasun yatis, and Y schal breke togidere irun barris.", "rotherham": "I, before thee, will go, And the hills, will I level—The doors of bronze, will I break in pieces, And the bars of iron, will I cut asunder;", "darby": "I will go before thee, and make the elevated places plain; I will break in pieces the brazen doors, and cut asunder the bars of iron;", "twenty": "", "jps": "I will go before thee, and make the crooked places straight; I will break in pieces the doors of brass, and cut in sunder the bars of iron;", "acv": "I will go before thee, and make the rough places smooth. I will break in pieces the doors of brass, and cut apart the bars of iron.", "anderson": "", "haweis": "", "noyes": "I will go before thee, And make the high places plain; I will break in pieces the gates of brass, And cut in sunder the bars of iron.", "webster": "I will go before thee, and make the crooked places straight: I will break in pieces the gates of brass, and cut asunder the bars of iron:", "vulgate": "ego ante te ibo et gloriosos terrae humiliabo portas aereas conteram et vectes ferreos confringam;", "brenton": "I will go before thee, and will level mountains: I will break to pieces brazen doors, and burst iron bars."}}, {"v": 3, "ref": "45:3", "o": "וְ/נָתַתִּ֤י לְ/ךָ֙ אוֹצְר֣וֹת חֹ֔שֶׁךְ וּ/מַטְמֻנֵ֖י מִסְתָּרִ֑ים לְמַ֣עַן תֵּדַ֗ע כִּֽי אֲנִ֧י יְהוָ֛ה הַ/קּוֹרֵ֥א בְ/שִׁמְ/ךָ֖ אֱלֹהֵ֥י יִשְׂרָאֵֽל", "en": {"kjv": "And I will give thee the treasures of darkness, and hidden riches of secret places, that thou mayest know that I, the Lord, which call thee by thy name, am the God of Israel.", "web": "I will give you the treasures of darkness, and hidden riches of secret places, that you may know that it is I, Yahweh, who call you by your name, even the God of Israel.", "bsb": "I will give you the treasures of darkness and the riches hidden in secret places, so that you may know that I am the LORD, the God of Israel, who calls you by name.", "asv": "and I will give thee the treasures of darkness, and hidden riches of secret places, that thou mayest know that it is I, Jehovah, who call thee by thy name, even the God of Israel.", "ylt": "And have given to thee treasures of darkness, Even treasures of secret places, So that thou knowest that I, Jehovah, Who am calling on thy name-- am the God of Israel.", "dra": "And I will give thee hidden treasures, and the concealed riches of secret places: that thou mayest know that I am the Lord who call thee by thy name, the God of Israel.", "bbe": "And I will give you the stores of the dark, and the wealth of secret places, so that you may be certain that I am the Lord, who gave you your name, even the God of Israel.", "geneva": "And I will giue thee the treasures of darkenesse, and the things hid in secret places, that thou maist know that I am the Lord which call thee by thy name, euen the God of Israel.", "wycliffe": "And Y schal yyue hid tresours to thee, and the priuy thingis of priuytees, that thou wite, that Y am the Lord, that clepe thi name, God of Israel,", "rotherham": "Then will I give thee The treasures of darkness, Even the hoards of hidden places,—That thou mayest get to know That I—Yahweh, who am calling thee by thy name, am the God of Israel.", "darby": "and I will give thee the treasures of darkness, and hidden riches of secret places; that thou mayest know that I, Jehovah, who call thee by name, [am] theGod of Israel.", "twenty": "", "jps": "And I will give thee the treasures of darkness, and hidden riches of secret places, that thou mayest know that I am HaShem, who call thee by thy name, even the G-d of Israel.", "acv": "And I will give thee the treasures of darkness, and hidden riches of secret places, that thou may know that it is I, Jehovah, who call thee by thy name, even the God of Israel.", "anderson": "", "haweis": "", "noyes": "I will give thee the treasures of darkness, And hidden riches of secret places, That thou mayst know that I am Jehovah Who calleth thee by name, the God of Israel.", "webster": "And I will give thee the treasures of darkness, and hidden riches of secret places, that thou mayest know that I, the LORD, who call [thee] by thy name, [am] the God of Israel.", "vulgate": "et dabo tibi thesauros absconditos et arcana secretorum ut scias quia ego Dominus qui voco nomen tuum Deus Israhel;", "brenton": "And I will give thee the treasures of darkness, I will open to thee hidden, unseen treasures, that thou mayest know that I, the Lord thy God, that call thee by name, am the God of Israel."}}, {"v": 4, "ref": "45:4", "o": "לְמַ֨עַן֙ עַבְדִּ֣/י יַעֲקֹ֔ב וְ/יִשְׂרָאֵ֖ל בְּחִירִ֑/י וָ/אֶקְרָ֤א לְ/ךָ֙ בִּ/שְׁמֶ֔/ךָ אֲכַנְּ/ךָ֖ וְ/לֹ֥א יְדַעְתָּֽ/נִי", "en": {"kjv": "For Jacob my servant’s sake, and Israel mine elect, I have even called thee by thy name: I have surnamed thee, though thou hast not known me.", "web": "For Jacob my servant’s sake, and Israel my chosen, I have called you by your name. I have given you a title, though you have not known me.", "bsb": "For the sake of Jacob My servant and Israel My chosen one, I call you by name; I have given you a title of honor, though you have not known Me.", "asv": "For Jacob my servant’s sake, and Israel my chosen, I have called thee by thy name: I have surnamed thee, though thou hast not known me.", "ylt": "For the sake of my servant Jacob, And of Israel My chosen, I call also thee by thy name, I surname thee, And thou hast not known Me.", "dra": "For the sake of my servant Jacob, and Israel my elect, I have even called thee by thy name: I have made a likeness of thee, and thou hast not known me.", "bbe": "Because of Jacob my servant, and Israel whom I have taken for myself, I have sent for you by name, giving you a name of honour, though you had no knowledge of me.", "geneva": "For Iaakob my seruants sake, and Israel mine elect, I will euen call thee by thy name and name thee, though thou hast not knowen me.", "wycliffe": "for my seruaunt Jacob, and Israel my chosun, and Y clepide thee bi thi name; Y licnyde thee, and thou knewist not me.", "rotherham": "For the sake of my servant Jacob, Even Israel my chosen Therefore have I called unto thee by thy name, I give thee a title though thou hast not known me,—", "darby": "For Jacob my servant's sake, and Israel mine elect, I have called thee by thy name; I surnamed thee, though thou didst not know me;", "twenty": "", "jps": "For the sake of Jacob My servant, and Israel Mine elect, I have called thee by thy name, I have surnamed thee, though thou hast not known Me.", "acv": "For Jacob my servant's sake, and Israel my chosen, I have called thee by thy name. I have surnamed thee, though thou have not known me.", "anderson": "", "haweis": "", "noyes": "For the sake of Jacob, my servant, And Israel, my chosen, I have called thee by thy name; I have spoken to thee as a friend, though thou hast not known me.", "webster": "For Jacob my servant's sake, and Israel my elect, I have even called thee by thy name: I have surnamed thee, though thou hast not known me:", "vulgate": "propter servum meum Iacob et Israhel electum meum et vocavi te in nomine tuo adsimilavi te et non cognovisti me;", "brenton": "For the sake of my servant Jacob, and Israel mine elect, I will call thee by thy name, and accept thee: but thou hast not known me."}}, {"v": 5, "ref": "45:5", "o": "אֲנִ֤י יְהוָה֙ וְ/אֵ֣ין ע֔וֹד זוּלָתִ֖/י אֵ֣ין אֱלֹהִ֑ים אֲאַזֶּרְ/ךָ֖ וְ/לֹ֥א יְדַעְתָּֽ/נִי", "en": {"kjv": "I am the Lord, and there is none else, there is no God beside me: I girded thee, though thou hast not known me:", "web": "I am Yahweh, and there is no one else. Besides me, there is no God. I will strengthen you, though you have not known me;", "bsb": "I am the LORD, and there is no other; there is no God but Me. I will equip you for battle, though you have not known Me,", "asv": "I am Jehovah, and there is none else; besides me there is no God. I will gird thee, though thou hast not known me;", "ylt": "I am Jehovah, and there is none else, Except Me there is no God, I gird thee, and thou hast not known Me.", "dra": "I am the Lord, and there is none else: there is no God besides me: I girded thee, and thou hast not known me:", "bbe": "I am the Lord, and there is no other; there is no God but me: I will make you ready for war, though you had no knowledge of me:", "geneva": "I am the Lord and there is none other: there is no God besides me: I girded thee though thou hast not knowen me,", "wycliffe": "Y am the Lord, and ther is no more; with out me is no God. Y haue gird thee, and thou knewist not me.", "rotherham": "I, am Yahweh, and there is none else, Besides me, there is no God,—I gird thee, though thou hast not known me:", "darby": "I [am] Jehovah, and there is none else; there is noGod beside me: I girded thee, and thou hast not known me;", "twenty": "", "jps": "I am HaShem, and there is none else, beside Me there is no G-d; I have girded thee, though thou hast not known Me;", "acv": "I am Jehovah, and there is none else. Besides me there is no God. I will gird thee, though thou have not known me,", "anderson": "", "haweis": "", "noyes": "I am Jehovah, and none else; There is no God besides me; I have girded thee, though thou hast not known me.", "webster": "I [am] the LORD, and [there is] none else, [there is] no God besides me: I girded thee, though thou hast not known me:", "vulgate": "ego Dominus et non est amplius extra me non est deus accinxi te et non cognovisti me;", "brenton": "For I am the Lord God, and there is no other God beside me; I strengthened thee, and thou hast not known me."}}, {"v": 6, "ref": "45:6", "o": "לְמַ֣עַן יֵדְע֗וּ מִ/מִּזְרַח שֶׁ֨מֶשׁ֙ וּ/מִ/מַּ֣עֲרָבָ֔/הּ כִּי אֶ֖פֶס בִּלְעָדָ֑/י אֲנִ֥י יְהוָ֖ה וְ/אֵ֥ין עֽוֹד", "en": {"kjv": "That they may know from the rising of the sun, and from the west, that there is none beside me. I am the Lord, and there is none else.", "web": "that they may know from the rising of the sun, and from the west, that there is no one besides me. I am Yahweh, and there is no one else.", "bsb": "so that all may know, from where the sun rises to where it sets, that there is none but Me; I am the LORD, and there is no other.", "asv": "that they may know from the rising of the sun, and from the west, that there is none besides me: I am Jehovah, and there is none else.", "ylt": "So that they know from the rising of the sun, And from the west, that there is none besides Me, I am Jehovah, and there is none else,", "dra": "That they may know who are from the rising of the sun, and they who are from the west, that there is none besides me. I am the Lord, and there is none else:", "bbe": "So that they may see from the east and from the west that there is no God but me: I am the Lord, and there is no other.", "geneva": "That they may knowe from the rising of the sunne and from the West, that there is none besides me. I am the Lord, and there is none other.", "wycliffe": "That thei that ben at the risyng of the sunne, and thei that ben at the west, know, that with out me is no God.", "rotherham": "That men may get to know. From the rising of the sun And from the west. That there is none besides me,—I, am Yahweh, and there is none else:", "darby": "— that they may know from the rising of the sun, and from the going down, that there is none beside me. I [am] Jehovah, and there is none else;", "twenty": "", "jps": "That they may know from the rising of the sun, and from the west, that there is none beside Me; I am HaShem; and there is none else;", "acv": "that they may know from the rising of the sun, and from the west, that there is none besides me. I am Jehovah, and there is none else.", "anderson": "", "haweis": "", "noyes": "That men may know from the rising of the sun, And from the West, that there is none besides me; I am Jehovah, and none else.", "webster": "That they may know from the rising of the sun, and from the west, that [there is] none besides me. I [am] the LORD, and [there is] none else.", "vulgate": "ut sciant hii qui ab ortu solis et qui ab occidente quoniam absque me non est ego Dominus et non est alter;", "brenton": "That they that come from the east and they that come from the west may know that there is no God but me. I am the Lord God, and there is none beside."}}, {"v": 7, "ref": "45:7", "o": "יוֹצֵ֥ר אוֹר֙ וּ/בוֹרֵ֣א חֹ֔שֶׁךְ עֹשֶׂ֥ה שָׁל֖וֹם וּ/ב֣וֹרֵא רָ֑ע אֲנִ֥י יְהוָ֖ה עֹשֶׂ֥ה כָל אֵֽלֶּה", "en": {"kjv": "I form the light, and create darkness: I make peace, and create evil: I the Lord do all these things.", "web": "I form the light, and create darkness. I make peace, and create calamity. I am Yahweh, who does all these things.", "bsb": "I form the light and create the darkness; I bring prosperity and create calamity. I, the LORD, do all these things.", "asv": "I form the light, and create darkness; I make peace, and create evil; I am Jehovah, that doeth all these things.", "ylt": "Forming light, and preparing darkness, Making peace, and preparing evil, I am Jehovah, doing all these things.'", "dra": "I form the light, and create darkness, I make peace, and create evil: I the Lord that do all these things.", "bbe": "I am the giver of light and the maker of the dark; causing blessing, and sending troubles; I am the Lord, who does all these things.", "geneva": "I forme the light and create darkenes: I make peace and create euill: I the Lord doe all these things.", "wycliffe": "Y am the Lord, and noon other God is; fourmynge liyt, and makynge derknessis, makynge pees, and fourmynge yuel; Y am the Lord, doynge alle these thingis.", "rotherham": "Forming light and creating darkness, Making prosperity, and creating misfortune,—I—Yahweh, who doeth all these.", "darby": "forming the light and creating darkness, making peace and creating evil: I, Jehovah, do all these things.", "twenty": "", "jps": "I form the light, and create darkness; I make peace, and create evil; I am HaShem, that doeth all these things.", "acv": "I form the light, and create darkness. I make peace, and create evil. I am Jehovah who does all these things.", "anderson": "", "haweis": "", "noyes": "I form the light, and create darkness; I make peace, and create evil; I, Jehovah, do all these things.", "webster": "I form the light, and create darkness: I make peace, and create evil: I the LORD do all these [things].", "vulgate": "formans lucem et creans tenebras faciens pacem et creans malum ego Dominus faciens omnia haec;", "brenton": "I am he that prepared light, and formed darkness; who make peace, and create evil; I am the Lord God, that does all these things."}}, {"v": 8, "ref": "45:8", "o": "הַרְעִ֤יפוּ שָׁמַ֨יִם֙ מִ/מַּ֔עַל וּ/שְׁחָקִ֖ים יִזְּלוּ צֶ֑דֶק תִּפְתַּח אֶ֣רֶץ וְ/יִפְרוּ יֶ֗שַׁע וּ/צְדָקָ֤ה תַצְמִ֨יחַ֙ יַ֔חַד אֲנִ֥י יְהוָ֖ה בְּרָאתִֽי/ו", "en": {"kjv": "Drop down, ye heavens, from above, and let the skies pour down righteousness: let the earth open, and let them bring forth salvation, and let righteousness spring up together; I the Lord have created it.", "web": "Distil, you heavens, from above, and let the skies pour down righteousness. Let the earth open, that it may produce salvation, and let it cause righteousness to spring up with it. I, Yahweh, have created it.", "bsb": "Drip down, O heavens, from above, and let the skies pour down righteousness. Let the earth open up that salvation may sprout and righteousness spring up with it; I, the LORD, have created it.", "asv": "Distil, ye heavens, from above, and let the skies pour down righteousness: let the earth open, that it may bring forth salvation, and let it cause righteousness to spring up together; I, Jehovah, have created it.", "ylt": "Drop, ye heavens, from above, And clouds do cause righteousness to flow, Earth openeth, and they are fruitful, Salvation and righteousness spring up together, I, Jehovah, have prepared it.", "dra": "Drop down dew, ye heavens, from above, and let the clouds rain the just: let the earth be opened, and bud forth a saviour: and let justice spring up together: I the Lord have created him.", "bbe": "Let righteousness come down, O heavens, from on high, and let the sky send it down like rain: let the earth be open to give the fruit of salvation, causing righteousness to come up with it; I the Lord have made it come about.", "geneva": "Ye heauens, send the dewe from aboue, and let the cloudes droppe downe righteousnesse: let the earth open, and let saluation and iustice growe foorth: let it bring them foorth together: I the Lord haue created him.", "wycliffe": "Heuenes, sende ye out deew fro aboue, and cloudis, reyne a iust man; the erthe be openyde, and brynge forth the sauyour, and riytfulnesse be borun togidere; Y the Lord haue maad hym of nouyt.", "rotherham": "Let the drops fall ye heavens, from above, Yea, let, the skies, pour down righteousness,—Let the earth open and let them bear as their fruit—deliverance And let, justice, spring forth therewith, I—Yahweh, have created it.", "darby": "Drop down, [ye] heavens, from above, and let the skies pour down righteousness; let the earth open, and let them bring forth salvation, and with it let righteousness spring up. I, Jehovah, have created it.", "twenty": "", "jps": "Drop down, ye heavens, from above, and let the skies pour down righteousness; let the earth open, that they may bring forth salvation, and let her cause righteousness to spring up together; I HaShem have created it.", "acv": "Distil, ye heavens, from above, and let the skies pour down righteousness. Let the earth open that it may bring forth salvation, and let it cause righteousness to spring up together. I, Jehovah, have created it.", "anderson": "", "haweis": "", "noyes": "Pour forth, ye heavens, from above; Ye clouds, shower down prosperity! Let the earth open, and bring forth salvation; Yea, let righteousness spring up together! I, Jehovah, create it.", "webster": "Drop down, ye heavens, from above, and let the skies pour down righteousness: let the earth open, and let them bring forth salvation, and let righteousness spring up together; I the LORD have created it.", "vulgate": "rorate caeli desuper et nubes pluant iustum aperiatur terra et germinet salvatorem et iustitia oriatur simul ego Dominus creavi eum;", "brenton": "Let the heaven rejoice from above, and let the clouds rain righteousness: let the earth bring forth, and blossom with mercy, and bring forth righteousness likewise: I am the Lord that created thee."}}, {"v": 9, "ref": "45:9", "o": "ה֗וֹי רָ֚ב אֶת יֹ֣צְר֔/וֹ חֶ֖רֶשׂ אֶת חַרְשֵׂ֣י אֲדָמָ֑ה הֲ/יֹאמַ֨ר חֹ֤מֶר לְ/יֹֽצְר/וֹ֙ מַֽה תַּעֲשֶׂ֔ה וּ/פָעָלְ/ךָ֖ אֵין יָדַ֥יִם לֽ/וֹ", "en": {"kjv": "Woe unto him that striveth with his Maker! Let the potsherd strive with the potsherds of the earth. Shall the clay say to him that fashioneth it, What makest thou? or thy work, He hath no hands?", "web": "Woe to him who strives with his Maker— a clay pot among the clay pots of the earth! Shall the clay ask him who fashions it, ‘What are you making?’ or your work, ‘He has no hands?’", "bsb": "Woe to him who quarrels with his Maker— one clay pot among many. Does the clay ask the potter, ‘What are you making?’ Does your work say, ‘He has no hands’?", "asv": "Woe unto him that striveth with his Maker! a potsherd among the potsherds of the earth! Shall the clay say to him that fashioneth it, What makest thou? or thy work, He hath no hands?", "ylt": "Woe to him who is striving with his Former, (A potsherd with potsherds of the ground!) Doth clay say to its Framer, `What dost thou?' And thy work, `He hath no hands?'", "dra": "Woe to him that gainsayeth his maker, a sherd of the earthen pots: shall the clay say to him that fashioneth it: What art thou making, and thy work is without hands?", "bbe": "Cursed is he who has an argument with his Maker, the pot which has an argument with the Potter! Will the wet earth say to him who is working with it, What are you doing, that your work has nothing by which it may be gripped?", "geneva": "Woe be vnto him that striueth with his maker, the potsherd with the potsherds of the earth: shall the clay say to him that facioneth it, What makest thou? or thy worke, It hath none hands?", "wycliffe": "Wo to hym that ayen seith his maker, a tiel stoon of erthe of Sannys. Whether clei seith to his pottere, What makist thou, and thi werk is withouten hondis?", "rotherham": "Alas for him who contendeth with his Fashioner,—A potsherd, [should contend] with the potsherds of the ground! Shall it be said by the clay, unto him that is fashioning it, What wouldst thou make? Or, thy work say, of thee, He hath no hands?", "darby": "Woe unto him that striveth with his Maker! Let a potsherd [strive] with the potsherds of the earth. Shall the clay say to him that formeth it, What makest thou? Or thy work, He hath no hands?", "twenty": "", "jps": "Woe unto him that striveth with his Maker, as a potsherd with the potsherds of the earth! Shall the clay say to him that fashioned it: 'What makest thou?' Or: 'Thy work, it hath no hands'?", "acv": "Woe to him who strives with his maker, a potsherd among the potsherds of the earth! Shall the clay say to him that fashions it, What are thou making? or thy work, He has no hands?", "anderson": "", "haweis": "", "noyes": "Woe to him that contendeth with his Maker! A potsherd of the potsherds of the earth! Shall the clay say to him that fashioneth it, What makest thou? Or thy work say of thee, He hath no hands?", "webster": "Woe to him that contendeth with his Maker! [Let] the potsherd [contend] with the potsherds of the earth. Shall the clay say to him that fashioneth it, What makest thou? or thy work, He hath no hands?", "vulgate": "vae qui contradicit fictori suo testa de samiis terrae numquid dicet lutum figulo suo quid facis et opus tuum absque manibus est;", "brenton": "What excellent thing have I prepared as clay of the potter? Will the ploughman plough the earth all day? shall the clay say to the potter, What art thou doing that thou dost not work, nor hast hands? shall the thing formed answer him that formed it?"}}, {"v": 10, "ref": "45:10", "o": "ה֛וֹי אֹמֵ֥ר לְ/אָ֖ב מַה תּוֹלִ֑יד וּ/לְ/אִשָּׁ֖ה מַה תְּחִילִֽי/ן", "en": {"kjv": "Woe unto him that saith unto his father, What begettest thou? or to the woman, What hast thou brought forth?", "web": "Woe to him who says to a father, ‘What have you become the father of?’ or to a mother, ‘To what have you given birth?’”", "bsb": "Woe to him who says to his father, ‘What have you begotten?’ or to his mother, ‘What have you brought forth?’”", "asv": "Woe unto him that saith unto a father, What begettest thou? or to a woman, With what travailest thou?", "ylt": "Woe to him who is saying to a father, `What dost thou beget?' Or to a wife, `What dost thou bring forth?", "dra": "Woe to him that saith to his father: Why begettest thou? and to the woman: Why dost thou bring forth?", "bbe": "Cursed is he who says to a father, To what are you giving life? or to a woman, What are you in birth-pains with?", "geneva": "Woe vnto him that sayeth to his father, What hast thou begotten? or to his mother, What hast thou brought foorth?", "wycliffe": "Wo to hym that seith to the fadir, What gendrist thou? and to a womman, What childist thou?", "rotherham": "Alas, for one who saith to a father, What begettest thou? Or to a woman What dost thou bring forth?", "darby": "Woe unto him that saith unto [his] father, What begettest thou? Or to [his] mother, What hast thou brought forth?", "twenty": "", "jps": "Woe unto him that saith unto his father. 'Wherefore begettest thou?' Or to a woman: 'Wherefore travailest thou?'", "acv": "Woe to him who says to a father, What are thou begetting? or to a woman, With what are thou travailing?", "anderson": "", "haweis": "", "noyes": "Woe to him that saith to his father, Why dost thou beget? Or to his mother, Why dost thou bring forth?", "webster": "Woe to him that saith to [his] father, What begettest thou? or to the woman, What hast thou brought forth?", "vulgate": "vae qui dicit patri quid generas et mulieri quid parturis;", "brenton": "As though one should say to his father, What wilt thou beget me? and to his mother, What art thou bringing forth?"}}, {"v": 11, "ref": "45:11", "o": "כֹּֽה אָמַ֧ר יְהוָ֛ה קְד֥וֹשׁ יִשְׂרָאֵ֖ל וְ/יֹצְר֑/וֹ הָ/אֹתִיּ֣וֹת שְׁאָל֔וּ/נִי עַל בָּנַ֛/י וְ/עַל פֹּ֥עַל יָדַ֖/י תְּצַוֻּֽ/נִי", "en": {"kjv": "Thus saith the Lord, the Holy One of Israel, and his Maker, Ask me of things to come concerning my sons, and concerning the work of my hands command ye me.", "web": "Thus says Yahweh, the Holy One of Israel, and his Maker: “You ask me about the things that are to come, concerning my sons, and you command me concerning the work of my hands!", "bsb": "Thus says the LORD, the Holy One of Israel, and its Maker: “How dare you question Me about My sons, or instruct Me in the work of My hands?", "asv": "Thus saith Jehovah, the Holy One of Israel, and his Maker: Ask me of the things that are to come; concerning my sons, and concerning the work of my hands, command ye me.", "ylt": "Thus said Jehovah, The Holy One of Israel, and his Former: Ask Me of the things coming concerning My sons, Yea, concerning the work of My hands, ye command Me.'", "dra": "Thus saith the Lord the Holy One of Israel, his maker: Ask me of things to come, concerning my children, and concerning the work of my hands give ye charge to me.", "bbe": "The Lord, the Holy One of Israel, and his Maker, says, Will you put a question to me about the things which are to come, or will you give me orders about my sons, and the work of my hands?", "geneva": "Thus saith the Lord, the holy one of Israel, and his maker, Aske me of things to come concerning my sonnes, and concerning the workes of mine hands: commande you me.", "wycliffe": "The Lord, the hooli of Israel, the fourmere therof, seith these thingis, Axe ye me thingis to comynge on my sones, and sende ye to me on the werkis of myn hondis.", "rotherham": "Thus, saith, Yahweh, The Holy One of Israel And his Fashioner, As to things to come, they have asked me, Concerning my sons and concerning the work of my hands, they would command me!", "darby": "Thus saith Jehovah, the Holy One of Israel, and his Maker: Ask me of the things to come; concerning my sons, and concerning the work of my hands, command ye me.", "twenty": "", "jps": "Thus saith HaShem, the Holy One of Israel, and his Maker: Ask Me of the things that are to come; concerning My sons, and concerning the work of My hands, command ye Me.", "acv": "Thus says Jehovah, the Holy One of Israel and his maker: Ask me of the things that are to come concerning my sons. And command ye me concerning the work of my hands.", "anderson": "", "haweis": "", "noyes": "Thus saith Jehovah, the Holy One of Israel, and his Maker, Ask of me concerning things to come; My children, the work of my hands, leave them to me!", "webster": "Thus saith the LORD, the Holy One of Israel, and his Maker, Ask me of things to come concerning my sons, and concerning the work of my hands command ye me.", "vulgate": "haec dicit Dominus Sanctus Israhel plastes eius ventura interrogate me super filios meos et super opus manuum mearum mandastis mihi;", "brenton": "For thus saith the Lord God, the Holy One of Israel, who has formed the things that are to come, Enquire of me concerning my sons, and concerning the works of my hands command me."}}, {"v": 12, "ref": "45:12", "o": "אָֽנֹכִי֙ עָשִׂ֣יתִי אֶ֔רֶץ וְ/אָדָ֖ם עָלֶ֣י/הָ בָרָ֑אתִי אֲנִ֗י יָדַ/י֙ נָט֣וּ שָׁמַ֔יִם וְ/כָל צְבָאָ֖/ם צִוֵּֽיתִי", "en": {"kjv": "I have made the earth, and created man upon it: I, even my hands, have stretched out the heavens, and all their host have I commanded.", "web": "I have made the earth, and created man on it. I, even my hands, have stretched out the heavens; and I have commanded all their army.", "bsb": "It is I who made the earth and created man upon it. It was My hands that stretched out the heavens, and I ordained all their host.", "asv": "I have made the earth, and created man upon it: I, even my hands, have stretched out the heavens; and all their host have I commanded.", "ylt": "I made earth, and man on it prepared, I--My hands stretched out the heavens, And all their host I have commanded.", "dra": "I made the earth: and I created man upon it: my hand stretched forth the heavens, and I have commanded all their host.", "bbe": "I have made the earth, forming man on it: by my hands the heavens have been stretched out, and all the stars put in their ordered places.", "geneva": "I haue made the earth, and created man vpon it: I, whose hands haue spred out the heauens, I haue euen commanded all their armie.", "wycliffe": "Y made erthe, and Y made a man on it; myn hondis helden abrood heuenes, and Y comaundide to al the knyythod of tho.", "rotherham": "I, made the earth, And man upon it, I created,—I—mine own hands, stretched out the heavens, And all their host, I commanded:", "darby": "It is I that have made the earth, and created man upon it; it is I, my hands, that have stretched out the heavens, and all their host have I commanded.", "twenty": "", "jps": "I, even I, have made the earth, and created man upon it; I, even My hands, have stretched out the heavens, and all their host have I commanded.", "acv": "I have made the earth, and created man upon it. I, even my hands, have stretched out the heavens, and all their host I have commanded.", "anderson": "", "haweis": "", "noyes": "I made the earth, And created man upon it; My hands spread out the heavens, And all their host did I arrange.", "webster": "I have made the earth, and created man upon it: I, [even] my hands, have stretched out the heavens, and all their host have I commanded.", "vulgate": "ego feci terram et hominem super eam creavi ego manus meae tetenderunt caelos et omni militiae eorum mandavi;", "brenton": "I have made the earth, and man upon it: I with my hand have established the heaven; I have given commandment to all the stars."}}, {"v": 13, "ref": "45:13", "o": "אָנֹכִי֙ הַעִירֹתִ֣/הֽוּ בְ/צֶ֔דֶק וְ/כָל דְּרָכָ֖י/ו אֲיַשֵּׁ֑ר הֽוּא יִבְנֶ֤ה עִירִ/י֙ וְ/גָלוּתִ֣/י יְשַׁלֵּ֔חַ לֹ֤א בִ/מְחִיר֙ וְ/לֹ֣א בְ/שֹׁ֔חַד אָמַ֖ר יְהוָ֥ה צְבָאֽוֹת", "en": {"kjv": "I have raised him up in righteousness, and I will direct all his ways: he shall build my city, and he shall let go my captives, not for price nor reward, saith the Lord of hosts.", "web": "I have raised him up in righteousness, and I will make straight all his ways. He shall build my city, and he shall let my exiles go free, not for price nor reward,” says Yahweh of Armies.", "bsb": "I will raise up Cyrus in righteousness, and I will make all his ways straight. He will rebuild My city and set My exiles free, but not for payment or reward, says the LORD of Hosts.”", "asv": "I have raised him up in righteousness, and I will make straight all his ways: he shall build my city, and he shall let my exiles go free, not for price nor reward, saith Jehovah of hosts.", "ylt": "I have stirred him up in righteousness, And all his ways I make straight, He doth build My city, and My captivity doth send out, Not for price, nor for bribe, said Jehovah of Hosts.", "dra": "I have raised him up to justice, and I will direct all his ways: he shall build my city, and let go my captives, not for ransom, nor for presents, saith the Lord the God of hosts.", "bbe": "I have sent him out to overcome the nations, and I will make all his ways straight: I will give him the work of building my town, and he will let my prisoners go free, without price or reward, says the Lord of armies.", "geneva": "I haue raised him vp in righteousnesse, and I will direct all his wayes: he shall build my citie, and he shall let goe my captiues, not for price nor rewarde, saith the Lord of hostes.", "wycliffe": "Y reiside hym to riytfulnesse, and Y schal dresse alle hise weies; he schal bilde my citee, and he schal delyuere my prisoneris, not in prijs, nether in yiftis, seith the Lord of oostis.", "rotherham": "I, have roused him up in righteousness, And all his roads, will I level,—He, shall build my city, And my captives, shall he let go, Not for price, nor for bribe, Saith Yahweh of hosts.", "darby": "It is I that have raised him up in righteousness, and I will make all his ways straight: he shall build my city, and he shall let go my captives, not for price nor reward, saith Jehovah of hosts.", "twenty": "", "jps": "I have roused him up in victory, and I make level all his ways; he shall build My city, and he shall let Mine exiles go free, not for price nor reward, saith HaShem of hosts.", "acv": "I have raised him up in righteousness, and I will make straight all his ways. He shall build my city, and he shall let my exiles go free, not for price nor reward, says Jehovah of hosts.", "anderson": "", "haweis": "", "noyes": "I have raised him up for salvation, And I will make all his ways plain; He shall build my city, and release my captives, Not for price, and not for ransom, Saith Jehovah of hosts.", "webster": "I have raised him up in righteousness, and I will direct all his ways: he shall build my city, and he shall let go my captives, not for price nor reward, saith the LORD of hosts.", "vulgate": "ego suscitavi eum ad iustitiam et omnes vias eius dirigam ipse aedificabit civitatem meam et captivitatem meam dimittet non in pretio neque in muneribus dicit Dominus Deus exercituum;", "brenton": "I have raised him up to be a king with righteousness, and all his ways are right: he shall build my city, and shall turn the captivity of my people, not for ransoms, nor for rewards, saith the Lord of hosts."}}, {"v": 14, "ref": "45:14", "o": "כֹּ֣ה אָמַ֣ר יְהוָ֗ה יְגִ֨יעַ מִצְרַ֥יִם וּֽ/סְחַר כּוּשׁ֮ וּ/סְבָאִים֮ אַנְשֵׁ֣י מִדָּה֒ עָלַ֤יִ/ךְ יַעֲבֹ֨רוּ֙ וְ/לָ֣/ךְ יִֽהְי֔וּ אַחֲרַ֣יִ/ךְ יֵלֵ֔כוּ בַּ/זִּקִּ֖ים יַעֲבֹ֑רוּ וְ/אֵלַ֤יִ/ךְ יִֽשְׁתַּחֲוּוּ֙ אֵלַ֣יִ/ךְ יִתְפַּלָּ֔לוּ אַ֣ךְ בָּ֥/ךְ אֵ֛ל וְ/אֵ֥ין ע֖וֹד אֶ֥פֶס אֱלֹהִֽים", "en": {"kjv": "Thus saith the Lord, The labour of Egypt, and merchandise of Ethiopia and of the Sabeans, men of stature, shall come over unto thee, and they shall be thine: they shall come after thee; in chains they shall come over, and they shall fall down unto thee, they shall make supplication unto thee, saying, Surely God is in thee; and there is none else, there is no God.", "web": "Thus says Yahweh: “The labor of Egypt, and the merchandise of Ethiopia, and the Sabeans, men of stature, shall come over to you, and they shall be yours. They will go after you. They shall come over in chains; and they will bow down to you. They will make supplication to you: ‘Surely God is in you; and there is no one else. There is no other god.", "bsb": "This is what the LORD says: “The products of Egypt and the merchandise of Cush, along with the Sabeans, men of stature, will come over to you and will be yours; they will trudge behind you; they will come over in chains and bow down to you. They will confess to you: ‘God is indeed with you, and there is no other; there is no other God.’”", "asv": "Thus saith Jehovah, The labor of Egypt, and the merchandise of Ethiopia, and the Sabeans, men of stature, shall come over unto thee, and they shall be thine: they shall go after thee, in chains they shall come over; and they shall fall down unto thee, they shall make supplication unto thee, saying, Surely God is in thee; and there is none else, there is no God.", "ylt": "Thus said Jehovah, `The labour of Egypt, And the merchandise of Cush, And of the Sebaim--men of measure, Unto thee pass over, and thine they are, After thee they go, in fetters they pass over, And unto thee they bow themselves, Unto thee they pray: Only in thee is God, And there is none else, no other God.", "dra": "Thus saith the Lord: The labour of Egypt, and the merchandise of Ethiopia, and of Sabaim, men of stature shall come over to thee, and shall be thine: they shall walk after thee, they shall go bound with manacles: and they shall worship thee, and shall make supplication to thee: only in thee is God, and there is no God besides thee.", "bbe": "The Lord says, The workmen of Egypt, and the traders of Ethiopia, and the tall Sabaeans, will come over the sea to you, and they will be yours; they will go after you; in chains they will come over: and they will go down on their faces before you, and will make prayer to you, saying, Truly, God is among you; and there is no other God.", "geneva": "Thus sayth the Lord, The labour of Egypt, and the marchandise of Ethiopia, and of the Sabeans, men of stature shall come vnto thee, and they shall be thine: they shall follow thee, and shall goe in chaines: they shall fall downe before thee, and make supplication vnto thee, saying, Surely God is in thee, and there is none other God besides.", "wycliffe": "The Lord God seith these thingis, The trauel of Egipt, and the marchaundie of Ethiopie, and of Sabaym; hiy men schulen go to thee, and schulen be thine; thei schulen go aftir thee, thei schulen go boundun in manyclis, and schulen worschipe thee, and schulen biseche thee. God is oneli in thee, and with out thee is no God.", "rotherham": "Thus, saith Yahweh—The produce of Egypt and the gain of Ethiopia, and the Sabeans, men of great stature, Unto thee, shall come over, And thine, shall they become, After thee, shall they journey, In chains, shall they come over,—And unto thee, shall they bow down Unto thee, shall they pray [saying],—Surely, in thee, is a GOD And there is none else—no, God!", "darby": "Thus saith Jehovah: The wealth of Egypt, and the merchandise of Ethiopia and the Sabeans, men of stature, shall come over unto thee, and they shall be thine: they shall walk after thee; in chains they shall come over, and they shall bow down unto thee, they shall make supplication unto thee, [saying,] SurelyGod is in thee; and there is none else, no otherGod. ...", "twenty": "", "jps": "Thus saith HaShem: the labour of Egypt, and the merchandise of Ethiopia, and of the Sabeans, men of stature, shall come over unto thee, and they shall be thine; they shall go after thee, in chains they shall come over; and they shall fall down unto thee, they shall make supplication unto thee: Surely G-d is in thee, and there is none else, there is no other G-d.", "acv": "Thus says Jehovah: The labor of Egypt, and the merchandise of Ethiopia, and the Sabeans, men of stature, shall come over to thee, and they shall be thine. They shall go after thee. In chains they shall come over, and they shall fall down to thee. They shall make supplication to thee, saying, Surely God is in thee, and there is none else, no God.", "anderson": "", "haweis": "", "noyes": "Thus saith Jehovah: The wealth of Egypt and the merchandise of the Ethiopians and Sabeans, men of stature, Shall come over to thee, and be thine; They shall follow thee; in chains shall they pass along; They shall fall down to thee, and make supplication to thee: \"In thee alone is God, and there is none else; There is no other God.\"", "webster": "Thus saith the LORD, The labor of Egypt, and merchandise of Cush and of the Sabeans, men of stature, shall come over to thee, and they shall be thine: they shall come after thee; in chains they shall come over, and they shall fall down to thee, they shall make supplication to thee, [saying], Surely God [is] in thee; and [there is] none else, [there is] no God.", "vulgate": "haec dicit Dominus labor Aegypti et negotiatio Aethiopiae et Sabaim viri sublimes ad te transibunt et tui erunt post te ambulabunt vincti manicis pergent et te adorabunt teque deprecabuntur tantum in te est Deus et non est absque te deus;", "brenton": "Thus saith the Lord of hosts, Egypt has laboured for thee; and the merchandise of the Ethiopians, and the Sabeans, men of stature, shall pass over to thee, and shall be thy servants; and they shall follow after thee bound in fetters, and shall pass over to thee, and shall do obeisance to thee, and make supplication to thee: because God is in thee; and there is no God beside thee, O Lord."}}, {"v": 15, "ref": "45:15", "o": "אָכֵ֕ן אַתָּ֖ה אֵ֣ל מִסְתַּתֵּ֑ר אֱלֹהֵ֥י יִשְׂרָאֵ֖ל מוֹשִֽׁיעַ", "en": {"kjv": "Verily thou art a God that hidest thyself, O God of Israel, the Saviour.", "web": "Most certainly you are a God who hidden yourself, God of Israel, the Savior.’”", "bsb": "Truly You are a God who hides Himself, O God of Israel, the Savior.", "asv": "Verily thou art a God that hidest thyself, O God of Israel, the Saviour.", "ylt": "Surely Thou art a God hiding Thyself, God of Israel--Saviour!", "dra": "Verily thou art a hidden God, the God of Israel the saviour.", "bbe": "Truly, you have a secret God, the God of Israel is a Saviour!", "geneva": "Verely thou, O God, hidest thy selfe, O God, the Sauiour of Israel.", "wycliffe": "Verili thou art God hid, God, the sauyour of Israel.", "rotherham": "Surely, thou, art a GOD utterly hiding thyself,—O God of Israel, able to save!", "darby": "Verily thou art aGod that hidest thyself, OGod of Israel, the Saviour. ...", "twenty": "", "jps": "Verily Thou art a G-d that hidest Thyself, O G-d of Israel, the Saviour.", "acv": "Verily thou are a God who hides thyself, O God of Israel, the Savior.", "anderson": "", "haweis": "", "noyes": "Truly thou art a God that hidest thyself, O God of Israel, the saviour!", "webster": "Verily thou [art] a God that hidest thyself, O God of Israel, the Savior.", "vulgate": "vere tu es Deus absconditus Deus Israhel salvator;", "brenton": "For thou art God, yet we knew it not, the God of Israel, the Saviour."}}, {"v": 16, "ref": "45:16", "o": "בּ֥וֹשׁוּ וְ/גַֽם נִכְלְמ֖וּ כֻּלָּ֑/ם יַחְדָּו֙ הָלְכ֣וּ בַ/כְּלִמָּ֔ה חָרָשֵׁ֖י צִירִֽים", "en": {"kjv": "They shall be ashamed, and also confounded, all of them: they shall go to confusion together that are makers of idols.", "web": "They will be disappointed, yes, confounded, all of them. Those who are makers of idols will go into confusion together.", "bsb": "They will all be put to shame and humiliated; the makers of idols will depart together in disgrace.", "asv": "They shall be put to shame, yea, confounded, all of them; they shall go into confusion together that are makers of idols.", "ylt": "They have been ashamed, And they have even blushed--all of them, Together gone in confusion have those carving images.", "dra": "They are all confounded and ashamed: the forgers of errors are gone together into confusion.", "bbe": "All those who have gone against him will be put to shame; the makers of images will be made low.", "geneva": "All they shalbe ashamed and also confounded: they shall goe to confusion together, that are the makers of images.", "wycliffe": "Alle makeris of errours ben schent, and weren aschamed; thei yeden togidere in to confusioun.", "rotherham": "They have turned pale and even been put to shame, all of them,—Together have they gone into disgrace, have the makers of images:", "darby": "They shall be ashamed, and also confounded, all of them; they shall go away in confusion together, the makers of idols.", "twenty": "", "jps": "They shall be ashamed, yea, confounded, all of them; they shall go in confusion together that are makers of idols.", "acv": "They shall be put to shame, yea, confounded, all of them. They shall go into confusion together who are makers of idols.", "anderson": "", "haweis": "", "noyes": "They shall all be ashamed and confounded, They shall go to confusion together, That are makers of idols.", "webster": "They shall be ashamed, and also confounded, all of them: they shall go to confusion together [that are] makers of idols.", "vulgate": "confusi sunt et erubuerunt omnes simul abierunt in confusione fabricatores errorum;", "brenton": "All that are opposed to him shall be ashamed and confounded, and shall walk in shame: ye isles, keep a feast to me."}}, {"v": 17, "ref": "45:17", "o": "יִשְׂרָאֵל֙ נוֹשַׁ֣ע בַּ/יהוָ֔ה תְּשׁוּעַ֖ת עוֹלָמִ֑ים לֹא תֵבֹ֥שׁוּ וְ/לֹא תִכָּלְמ֖וּ עַד ע֥וֹלְמֵי עַֽד", "en": {"kjv": "But Israel shall be saved in the Lord with an everlasting salvation: ye shall not be ashamed nor confounded world without end.", "web": "Israel will be saved by Yahweh with an everlasting salvation. You will not be disappointed nor confounded to ages everlasting.", "bsb": "But Israel will be saved by the LORD with an everlasting salvation; you will not be put to shame or humiliated, to ages everlasting.", "asv": "But Israel shall be saved by Jehovah with an everlasting salvation: ye shall not be put to shame nor confounded world without end.", "ylt": "Israel hath been saved in Jehovah, A salvation age-during! Ye are not ashamed nor confounded Unto the ages of eternity!", "dra": "Israel is saved in the Lord with an eternal salvation: you shall not be confounded, and you shall not be ashamed for ever and ever.", "bbe": "But the Lord will make Israel free with an eternal salvation: you will not be put to shame or made low for ever and ever.", "geneva": "But Israel shall be saued in the Lord, with an euerlasting saluation: ye shall not be ashamed nor confounded worlde without ende.", "wycliffe": "Israel is sauyde in the Lord, bi euerlastynge helthe; ye schulen not be schent, and ye schulen not be aschamed, til in to the world of world.", "rotherham": "Israel, hath been delivered by Yahweh, with an age-abiding deliverance,—Ye shall neither turn pale nor he put to shame, unto the ages of futurity,.", "darby": "Israel shall be saved by Jehovah with an everlasting salvation: ye shall not be ashamed nor confounded, unto the ages of ages.", "twenty": "", "jps": "O Israel, that art saved by HaShem with an everlasting salvation; ye shall not be ashamed nor confounded world without end.", "acv": "But Israel shall be saved by Jehovah with an everlasting salvation. Ye shall not be put to shame nor confounded world without end.", "anderson": "", "haweis": "", "noyes": "But Israel shall be saved by Jehovah with an everlasting salvation; Ye shall never be ashamed, nor confounded.", "webster": "[But] Israel shall be saved in the LORD with an everlasting salvation: ye shall not be ashamed nor confounded world without end.", "vulgate": "Israhel salvatus est in Domino salute aeterna non confundemini et non erubescetis usque in saeculum saeculi;", "brenton": "Israel is saved by the Lord with an everlasting salvation: they shall not be ashamed nor confounded for evermore."}}, {"v": 18, "ref": "45:18", "o": "כִּ֣י כֹ֣ה אָֽמַר יְ֠הוָה בּוֹרֵ֨א הַ/שָּׁמַ֜יִם ה֣וּא הָ/אֱלֹהִ֗ים יֹצֵ֨ר הָ/אָ֤רֶץ וְ/עֹשָׂ/הּ֙ ה֣וּא כֽוֹנְנָ֔/הּ לֹא תֹ֥הוּ בְרָאָ֖/הּ לָ/שֶׁ֣בֶת יְצָרָ֑/הּ אֲנִ֥י יְהוָ֖ה וְ/אֵ֥ין עֽוֹד", "en": {"kjv": "For thus saith the Lord that created the heavens; God himself that formed the earth and made it; he hath established it, he created it not in vain, he formed it to be inhabited: I am the Lord; and there is none else.", "web": "For thus says Yahweh who created the heavens, the God who formed the earth and made it, who established it and didn’t create it a waste, who formed it to be inhabited: “I am Yahweh; and there is no other.", "bsb": "For thus says the LORD, who created the heavens—He is God; He formed the earth and fashioned it; He established it; He did not create it to be empty, but formed it to be inhabited: “I am the LORD, and there is no other.", "asv": "For thus saith Jehovah that created the heavens, the God that formed the earth and made it, that established it and created it not a waste, that formed it to be inhabited: I am Jehovah; and there is none else.", "ylt": "For thus said Jehovah, Creator of heaven, He is God, Former of earth, and its Maker, He established it--not empty He prepared it, For inhabiting He formed it: `I am Jehovah, and there is none else.", "dra": "For thus saith the Lord that created the heavens, God himself that formed the earth, and made it, the very maker thereof: he did not create it in vain: he formed it to be inhabited. I am the Lord, and there is no other.", "bbe": "For this is the word of the Lord who made the heavens; he is God; the maker and designer of the earth; who made it not to be a waste, but as a living-place for man: I am the Lord, and there is no other.", "geneva": "For thus saith the Lord (that created heauen, God himselfe, that formed the earth, and made it: he that prepared it, he created it not in vaine: he formed it to be inhabited) I am the Lord, and there is none other.", "wycliffe": "For whi the Lord makynge heuenes of nouyt, seith these thingis; he is God fourmynge erthe, and makinge it, he is the makere therof; he made it of noyt, not in veyn, but he formyde it, that it be enhabitid; Y am the Lord, and noon other is.", "rotherham": "For, Thus, saith Yahweh, Who created the heavens God himself! Who fashioned the earth—And made it Himself, established it, …Not a waste, created he it To be dwelt in, he fashioned it, …I, am Yahweh, and there is none else:", "darby": "For thus saith Jehovah who created the heavens,God himself who formed the earth and made it, he who established it, — not as waste did he create it: he formed it to be inhabited: — I [am] Jehovah, and there is none else.", "twenty": "", "jps": "For thus saith HaShem that created the heavens, He is G-d; that formed the earth and made it, He established it, He created it not a waste, He formed it to be inhabited: I am HaShem, and there is none else.", "acv": "For thus says Jehovah who created the heavens, the God who formed the earth and made it, who established it and did not create it a waste, who formed it to be inhabited: I am Jehovah, and there is none else.", "anderson": "", "haweis": "", "noyes": "For thus saith Jehovah, who created the heavens; The God that formed the earth and made it; he that made it firm; He created it not in vain; he formed it to be inhabited: I am Jehovah, and none else.", "webster": "For thus saith the LORD that created the heavens; God himself that formed the earth and made it; he hath established it, he created it not in vain, he formed it to be inhabited: I [am] the LORD; and [there is] none else.", "vulgate": "quia haec dicit Dominus creans caelos ipse Deus formans terram et faciens eam ipse plastes eius non in vanum creavit eam ut habitetur formavit eam ego Dominus et non est alius;", "brenton": "Thus saith the Lord that made the heaven, this God that created the earth, and made it; he marked it out, he made it not in vain, but formed it to be inhabited: I am the Lord, and there is none beside."}}, {"v": 19, "ref": "45:19", "o": "לֹ֧א בַ/סֵּ֣תֶר דִּבַּ֗רְתִּי בִּ/מְקוֹם֙ אֶ֣רֶץ חֹ֔שֶׁךְ לֹ֥א אָמַ֛רְתִּי לְ/זֶ֥רַע יַעֲקֹ֖ב תֹּ֣הוּ בַקְּשׁ֑וּ/נִי אֲנִ֤י יְהוָה֙ דֹּבֵ֣ר צֶ֔דֶק מַגִּ֖יד מֵישָׁרִֽים", "en": {"kjv": "I have not spoken in secret, in a dark place of the earth: I said not unto the seed of Jacob, Seek ye me in vain: I the Lord speak righteousness, I declare things that are right.", "web": "I have not spoken in secret, in a place of the land of darkness. I didn’t say to the seed of Jacob, ‘Seek me in vain.’ I, Yahweh, speak righteousness. I declare things that are right.", "bsb": "I have not spoken in secret, from a place in a land of darkness. I did not say to the descendants of Jacob, ‘Seek Me in a wasteland.’ I, the LORD, speak the truth; I say what is right.", "asv": "I have not spoken in secret, in a place of the land of darkness; I said not unto the seed of Jacob, Seek ye me in vain: I, Jehovah, speak righteousness, I declare things that are right.", "ylt": "Not in secret have I spoken, in a dark place of the earth, I have not said to the seed of Jacob, In vain seek ye Me, I am Jehovah, speaking righteousness, Declaring uprightness.", "dra": "I have not spoken in secret, in a dark place of the earth: I have not said to the seed of Jacob: Seek me in vain. I am the Lord that speak justice, that declare right things.", "bbe": "I have not given my word in secret, in a place in the underworld; I did not say to the seed of Jacob, Go into a waste land to make request of me: I the Lord say what is true, my word is righteousness.", "geneva": "I haue not spoken in secrete, neither in a place of darkenes in the earth: I saide not in vaine vnto the seede of Iaakob, Seeke you me: I the Lord doe speake righteousnesse, and declare righteous things.", "wycliffe": "Y spak not in hid place, not in a derk place of erthe; I seide not to the seed of Jacob, Seke ye me in veyn. Y am the Lord spekynge riytfulnesse, tellynge riytful thingis.", "rotherham": "Not in secret, have I spoken In a place of the earth that is dark,—I have not said unto the seed of Jacob, In a waste, seek ye me,—I, am Yahweh, Speaking the thing that is right, Declaring the things that are just.", "darby": "I have not spoken in secret, in a dark place of the earth; I said not unto the seed of Jacob, Seek me in vain: I [am] Jehovah, speaking righteousness, declaring things which are right.", "twenty": "", "jps": "I have not spoken in secret, in a place of the land of darkness; I said not unto the seed of Jacob: 'Seek ye Me in vain'; I HaShem speak righteousness, I declare things that are right.", "acv": "I have not spoken in secret, in a place of the land of darkness. I did not say to the seed of Jacob, Seek ye me in vain. I, Jehovah, speak righteousness. I declare things that are right.", "anderson": "", "haweis": "", "noyes": "I have not spoken in secret, in a dark place of the earth; I have not said to the race of Jacob, Seek ye me in vain! I, Jehovah, speak truth; I declare that which is right.", "webster": "I have not spoken in secret, in a dark place of the earth: I have not said to the seed of Jacob, Seek ye me in vain: I the LORD speak righteousness, I declare things that are right.", "vulgate": "non in abscondito locutus sum in loco terrae tenebroso non dixi semini Iacob frustra quaerite me ego Dominus loquens iustitiam adnuntians recta;", "brenton": "I have not spoken in secret, nor in a dark place of the earth: I said not to the seed of Jacob, Seek vanity: I, even I, am the Lord, speaking righteousness, and proclaiming truth."}}, {"v": 20, "ref": "45:20", "o": "הִקָּבְצ֥וּ וָ/בֹ֛אוּ הִֽתְנַגְּשׁ֥וּ יַחְדָּ֖ו פְּלִיטֵ֣י הַ/גּוֹיִ֑ם לֹ֣א יָדְע֗וּ הַ/נֹּֽשְׂאִים֙ אֶת עֵ֣ץ פִּסְלָ֔/ם וּ/מִתְפַּלְלִ֔ים אֶל אֵ֖ל לֹ֥א יוֹשִֽׁיעַ", "en": {"kjv": "Assemble yourselves and come; draw near together, ye that are escaped of the nations: they have no knowledge that set up the wood of their graven image, and pray unto a god that cannot save.", "web": "“Assemble yourselves and come. Draw near together, you who have escaped from the nations. Those have no knowledge who carry the wood of their engraved image, and pray to a god that can’t save.", "bsb": "Come, gather together, and draw near, you fugitives from the nations. Ignorant are those who carry idols of wood and pray to a god that cannot save.", "asv": "Assemble yourselves and come; draw near together, ye that are escaped of the nations: they have no knowledge that carry the wood of their graven image, and pray unto a god that cannot save.", "ylt": "Be gathered, and come in, Come nigh together, ye escaped of the nations, They have not known, Who are lifting up the wood of their graven image, And praying unto a god that saveth not.", "dra": "Assemble yourselves, and come, and draw near together, ye that are saved of the Gentiles: they have no knowledge that set up the wood of their graven work, and pray to a god that cannot save.", "bbe": "Come together, even come near, you nations who are still living: they have no knowledge who take up their image of wood, and make prayer to a god in whom is no salvation.", "geneva": "Assemble your selues, and come: drawe neere together, ye abiect of the Gentiles: they haue no knowledge, that set vp the wood of their idole, and pray vnto a god, that cannot saue them.", "wycliffe": "Be ye gaderid, and come ye, and neiye ye togidere, that ben sauyd of hethene men; thei that reisen a signe of her grauyng, knewen not, and thei preien a god that saueth not.", "rotherham": "Assemble yourselves and come Draw near together, ye escaped of the nations,—They know not Who carry the wood of their carved image, And pray unto a GOD who cannot save.", "darby": "Gather yourselves and come; draw near together, ye that are escaped of the nations. They have no knowledge that carry the wood of their graven image, and pray unto agod that cannot save.", "twenty": "", "jps": "Assemble yourselves and come, draw near together, ye that are escaped of the nations; they have no knowledge that carry the wood of their graven image, and pray unto a god that cannot save.", "acv": "Assemble yourselves and come, draw near together, ye that are escaped of the nations. They have no knowledge that carry the wood of their graven image, and pray to a god that cannot save.", "anderson": "", "haweis": "", "noyes": "Assemble yourselves and come; Gather yourselves together, ye that are escaped of the nations! They are without understanding, who carry about with them the wood of their graven image, And pray to a god that cannot save.", "webster": "Assemble yourselves and come; draw near together, ye [that have] escaped of the nations: they have no knowledge that set up the wood of their graven image, and pray to a god [that] cannot save.", "vulgate": "congregamini et venite et accedite simul qui salvati estis ex gentibus nescierunt qui levant lignum sculpturae suae et rogant deum non salvantem;", "brenton": "Assemble yourselves and come; take counsel together, ye that escape of the nations: they that set up wood, even their graven image, have no knowledge, nor they who pray to gods that do not save."}}, {"v": 21, "ref": "45:21", "o": "הַגִּ֣ידוּ וְ/הַגִּ֔ישׁוּ אַ֥ף יִֽוָּעֲצ֖וּ יַחְדָּ֑ו מִ֣י הִשְׁמִיעַ֩ זֹ֨את מִ/קֶּ֜דֶם מֵ/אָ֣ז הִגִּידָ֗/הּ הֲ/ל֨וֹא אֲנִ֤י יְהוָה֙ וְ/אֵֽין ע֤וֹד אֱלֹהִים֙ מִ/בַּלְעָדַ֔/י אֵֽל צַדִּ֣יק וּ/מוֹשִׁ֔יעַ אַ֖יִן זוּלָתִֽ/י", "en": {"kjv": "Tell ye, and bring them near; yea, let them take counsel together: who hath declared this from ancient time? who hath told it from that time? have not I the Lord? and there is no God else beside me; a just God and a Saviour; there is none beside me.", "web": "Declare and present it. Yes, let them take counsel together. Who has shown this from ancient time? Who has declared it of old? Haven’t I, Yahweh? There is no other God besides me, a just God and a Savior; There is no one besides me.", "bsb": "Speak up and present your case— yes, let them take counsel together. Who foretold this long ago? Who announced it from ancient times? Was it not I, the LORD? There is no other God but Me, a righteous God and Savior; there is none but Me.", "asv": "Declare ye, and bring it forth; yea, let them take counsel together: who hath showed this from ancient time? who hath declared it of old? have not I, Jehovah? and there is no God else besides me, a just God and a Saviour; there is none besides me.", "ylt": "Declare ye, and bring near, Yea, they take counsel together, Who hath proclaimed this from of old? From that time hath declared it? Is it not I--Jehovah? And there is no other god besides Me, A God righteous and saving, there is none save Me.", "dra": "Tell ye, and come, and consult together: who hath declared this from the beginning, who hath foretold this from that time? Have not I the Lord, and there is no God else besides me? A just God and a saviour, there is none besides me.", "bbe": "Give the word, put forward your cause, let us have a discussion together: who has given news of this in the past? who made it clear in early times? did not I, the Lord? and there is no God but me; a true God and a saviour; there is no other.", "geneva": "Tell ye and bring them, and let them take counsell together, who hath declared this from the beginning? or hath tolde it of olde? Haue not I the Lord? and there is none other God beside me, a iust God, and a Sauiour: there is none beside me.", "wycliffe": "Telle ye, and come ye, and take ye councel togidere. Who made this herd fro the bigynnyng? fro that tyme Y bifor seide it. Whether Y am not the Lord, and no God is ferthere with out me? God riytful and sauynge is noon, outakun me.", "rotherham": "Tell ye—and bring near, Yea let them take counsel, together,—Who let this be known aforetime. In time past, declared it? Was it not, I—Yahweh? And there is none else that is God besides me, A GOD, righteous and ready to save, There is none, besides me!", "darby": "Declare and bring [them] near; yea, let them take counsel together: who hath caused this to be heard from ancient time? [who] hath declared it long ago? Is it not I, Jehovah? And there is noGod else beside me; a justGod and a Saviour, there is none besides me.", "twenty": "", "jps": "Declare ye, and bring them near, yea, let them take counsel together: Who hath announced this from ancient time, and declared it of old? Have not I HaShem? And there is no G-d else beside Me, a just G-d and a Saviour; there is none beside Me.", "acv": "Declare ye, and bring it forth. Yea, let them take counsel together. Who has shown this from ancient time? Who has declared it of old? Have not I, Jehovah? And there is no other God besides me, a just God and a Savior. There is none besides me.", "anderson": "", "haweis": "", "noyes": "Proclaim ye, and bring them near, And let them take counsel together: Who hath made this known from ancient time? Who hath declared it of old? Is it not I, Jehovah, besides whom there is no God? A God that uttereth truth, and giveth salvation; there is none besides me.", "webster": "Tell ye, and bring [them] near; yes, let them take counsel together: who hath declared this from ancient time? [who] hath told it from that time? [have] not I the LORD? and [there is] no God else besides me; a just God and a Savior; [there is] none besides me.", "vulgate": "adnuntiate et venite et consiliamini simul quis auditum fecit hoc ab initio ex tunc praedixit illud numquid non ego Dominus et non est ultra Deus absque me Deus iustus et salvans non est praeter me;", "brenton": "If they will declare, let them draw nigh, that they may know together, who has caused these things to be heard from the beginning: then was it told you. I am God, and there is not another beside me; a just God and a Saviour; there is none but me."}}, {"v": 22, "ref": "45:22", "o": "פְּנוּ אֵלַ֥/י וְ/הִוָּשְׁע֖וּ כָּל אַפְסֵי אָ֑רֶץ כִּ֥י אֲנִי אֵ֖ל וְ/אֵ֥ין עֽוֹד", "en": {"kjv": "Look unto me, and be ye saved, all the ends of the earth: for I am God, and there is none else.", "web": "“Look to me, and be saved, all the ends of the earth; for I am God, and there is no other.", "bsb": "Turn to Me and be saved, all the ends of the earth; for I am God, and there is no other.", "asv": "Look unto me, and be ye saved, all the ends of the earth; for I am God, and there is none else.", "ylt": "Turn to Me, and be saved, all ends of the earth, For I am God, and there is none else.", "dra": "Be converted to me, and you shall be saved, all ye ends of the earth: for I am God, and there is no other.", "bbe": "Let your hearts be turned to me, so that you may have salvation, all the ends of the earth: for I am God, and there is no other.", "geneva": "Looke vnto me, and ye shall be saued: all the endes of the earth shall be saued: for I am God, and there is none other.", "wycliffe": "Alle the coostis of erthe, be ye conuertid to me, and ye schulen be saaf; for Y am the Lord, and noon other is.", "rotherham": "Turn unto me—and be ye saved, all ye ends of the earth,—For, I, am GOD, and there is none else.", "darby": "Look unto me, and be ye saved, all the ends of the earth: for I [am]God, and there is none else.", "twenty": "", "jps": "Look unto Me, and be ye saved, all the ends of the earth; for I am G-d, and there is none else.", "acv": "Look to me, and be ye saved, all the ends of the earth, for I am God, and there is none else.", "anderson": "", "haweis": "", "noyes": "Look to me, and be saved, all ye ends of the earth! For I am God, and there is none else.", "webster": "Look to me, and be ye saved, all the ends of the earth: for I [am] God, and [there is] none else.", "vulgate": "convertimini ad me et salvi eritis omnes fines terrae quia ego Deus et non est alius;", "brenton": "Turn ye to me, and ye shall be saved, ye that come from the end of the earth: I am God, and there is none other."}}, {"v": 23, "ref": "45:23", "o": "בִּ֣/י נִשְׁבַּ֔עְתִּי יָצָ֨א מִ/פִּ֧/י צְדָקָ֛ה דָּבָ֖ר וְ/לֹ֣א יָשׁ֑וּב כִּי לִ/י֙ תִּכְרַ֣ע כָּל בֶּ֔רֶךְ תִּשָּׁבַ֖ע כָּל לָשֽׁוֹן", "en": {"kjv": "I have sworn by myself, the word is gone out of my mouth in righteousness, and shall not return, That unto me every knee shall bow, every tongue shall swear.", "web": "I have sworn by myself, the word has gone out of my mouth in righteousness, and will not return, that to me every knee shall bow, every tongue shall take an oath.", "bsb": "By Myself I have sworn; truth has gone out from My mouth, a word that will not be revoked: Every knee will bow before Me, every tongue will swear allegiance.", "asv": "By myself have I sworn, the word is gone forth from my mouth in righteousness, and shall not return, that unto me every knee shall bow, every tongue shall swear.", "ylt": "By Myself I have sworn, Gone out from my mouth in righteousness hath a word, And it turneth not back, That to Me, bow doth every knee, every tongue swear.", "dra": "I have sworn by myself, the word of justice shall go out of my mouth, and shall not return:", "bbe": "By myself have I taken an oath, a true word has gone from my mouth, and will not be changed, that to me every knee will be bent, and every tongue will give honour.", "geneva": "I haue sworne by my selfe: the worde is gone out of my mouth in righteousnesse, and shall not returne, That euery knee shall bowe vnto me, and euery tongue shall sweare by me.", "wycliffe": "Y swoor in my silf, a word of riytfulnesse schal go out of my mouth, and it schal not turne ayen;", "rotherham": "By myself, have I sworn, Gone forth out of my mouth, is righteousness as a decree And shall not turn back,—That, unto myself, Shall bow every knee, Shall swear every tongue:", "darby": "I have sworn by myself, the word is gone out of my mouth [in] righteousness and shall not return, that unto me every knee shall bow, every tongue shall swear.", "twenty": "", "jps": "By Myself have I sworn, the word is gone forth from My mouth in righteousness, and shall not come back, that unto Me every knee shall bow, every tongue shall swear.", "acv": "By myself I have sworn, the word has gone forth from my mouth in righteousness, and shall not return, that to me every knee shall bow, every tongue will confess to God.", "anderson": "", "haweis": "", "noyes": "By myself have I sworn, The truth hath gone from my mouth, The word, that shall not return, That to me every knee shall bow, That to me every tongue shall swear.", "webster": "I have sworn by myself, the word is gone out of my mouth [in] righteousness, and shall not return, That to me every knee shall bow, every tongue shall swear.", "vulgate": "in memet ipso iuravi egredietur de ore meo iustitiae verbum et non revertetur quia mihi curvabunt omnia genu et iurabit omnis lingua;", "brenton": "By myself I swear, righteousness shall surely proceed out of my mouth; my words shall not be frustrated; that to me every knee shall bend, and every tongue shall swear by God,"}}, {"v": 24, "ref": "45:24", "o": "אַ֧ךְ בַּ/יהוָ֛ה לִ֥/י אָמַ֖ר צְדָק֣וֹת וָ/עֹ֑ז עָדָי/ו֙ יָב֣וֹא וְ/יֵבֹ֔שׁוּ כֹּ֖ל הַ/נֶּחֱרִ֥ים בּֽ/וֹ", "en": {"kjv": "Surely, shall one say, in the Lord have I righteousness and strength: even to him shall men come; and all that are incensed against him shall be ashamed.", "web": "They will say of me, ‘There is righteousness and strength only in Yahweh.’” Even to him shall men come; and all those who were incensed against him shall be disappointed.", "bsb": "Surely they will say of Me, ‘In the LORD alone are righteousness and strength.’” All who rage against Him will come to Him and be put to shame.", "asv": "Only in Jehovah, it is said of me, is righteousness and strength; even to him shall men come; and all they that were incensed against him shall be put to shame.", "ylt": "Only in Jehovah, said hath one, Have I righteousness and strength, Unto Him he cometh in, And ashamed are all those displeased with Him.", "dra": "For every knee shall be bowed to me, and every tongue shall swear.", "bbe": "Only in the Lord will Jacob overcome and be strong: together all those who were angry with him will be put to shame and come to destruction.", "geneva": "Surely he shall say, In the Lord haue I righteousnesse and strength: he shall come vnto him, and all that prouoke him, shall be ashamed.", "wycliffe": "for ech kne schal be bowid to me, and ech tunge schal swere.", "rotherham": "Only in Yahweh—for me, Hath one said, Is there righteousness and strength, Unto him, shall come and turn pale—All who have been incensed against him:", "darby": "Only in Jehovah, shall one say, have I righteousness and strength. To him shall [men] come; and all that are incensed against him shall be ashamed.", "twenty": "", "jps": "Only in HaShem, shall one say of Me, is victory and strength; even to Him shall men come in confusion, all they that were incensed against Him.", "acv": "Only in Jehovah, it is said of me, is righteousness and strength. Even to him men shall come, and all those who were incensed against him shall be put to shame.", "anderson": "", "haweis": "", "noyes": "\"Only in Jehovah,\" shall men say, \"Is salvation and strength; To him shall come and be put to shame, All that are incensed against him.\"", "webster": "Surely, shall [one] say, in the LORD have I righteousness and strength: [even] to him shall [men] come; and all that are incensed against him shall be ashamed.", "vulgate": "ergo in Domino dicet meae sunt iustitiae et imperium ad eum venient et confundentur omnes qui repugnant ei;", "brenton": "saying, Righteousness and glory shall come to him: and all that remove them from their borders shall be ashamed."}}, {"v": 25, "ref": "45:25", "o": "בַּ/יהוָ֛ה יִצְדְּק֥וּ וְ/יִֽתְהַלְל֖וּ כָּל זֶ֥רַע יִשְׂרָאֵֽל", "en": {"kjv": "In the Lord shall all the seed of Israel be justified, and shall glory.", "web": "In Yahweh shall all the seed of Israel be justified, and shall glory.", "bsb": "In the LORD all descendants of Israel will be justified and will exult.", "asv": "In Jehovah shall all the seed of Israel be justified, and shall glory.", "ylt": "In Jehovah are all the seed of Israel justified, And they boast themselves.'", "dra": "Therefore shall he say: In the Lord are my justices and empire: they shall come to him, and all that resist him shall be confounded.", "bbe": "In the Lord will all the seed of Israel get their rights, and they will give glory to him.", "geneva": "The whole seede of Israel shall be iustified, and glorie in the Lord.", "wycliffe": "Therfor thei schulen sei in the Lord, Riytfulnessis and empire ben myne; alle that fiyten ayens hym schulen come to hym, and schulen be aschamed.", "rotherham": "In Yahweh, shall be justified and shall boast themselves—All the seed of Israel.", "darby": "In Jehovah shall all the seed of Israel be justified, and shall glory.", "twenty": "", "jps": "In HaShem shall all the seed of Israel be justified, and shall glory.", "acv": "In Jehovah all the seed of Israel shall be justified, and shall glory.", "anderson": "", "haweis": "", "noyes": "Through Jehovah shall all the race of Israel be delivered, And in him shall they glory.", "webster": "In the LORD shall all the seed of Israel be justified, and shall glory.", "vulgate": "in Domino iustificabitur et laudabitur omne semen Israhel;", "brenton": "By the Lord shall they be justified, and in God shall all the seed of the children of Israel be glorified."}}]}, {"c": 46, "verses": [{"v": 1, "ref": "46:1", "o": "כָּרַ֥ע בֵּל֙ קֹרֵ֣ס נְב֔וֹ הָיוּ֙ עֲצַבֵּי/הֶ֔ם לַ/חַיָּ֖ה וְ/לַ/בְּהֵמָ֑ה נְשֻׂאֹתֵי/כֶ֣ם עֲמוּס֔וֹת מַשָּׂ֖א לַ/עֲיֵפָֽה", "en": {"kjv": "Bel boweth down, Nebo stoopeth, their idols were upon the beasts, and upon the cattle: your carriages were heavy loaden; they are a burden to the weary beast.", "web": "Bel bows down, Nebo stoops; their idols are on the animals, and on the livestock: the things that you carried about are made a load, a burden to the weary.", "bsb": "Bel crouches; Nebo cowers. Their idols weigh down beasts and cattle. The images you carry are burdensome, a load to the weary animal.", "asv": "Bel boweth down, Nebo stoopeth; their idols are upon the beasts, and upon the cattle: the things that ye carried about are made a load, a burden to the weary beast.", "ylt": "Bowed down hath Bel, stooping is Nebo, Their idols have been for the beast and for cattle, Your burdens are loaded, a burden to the weary.", "dra": "Bel is broken, Nebo is destroyed: their idols are put upon beasts and cattle, your burdens of heavy weight even unto weariness.", "bbe": "Bel is bent down, Nebo is falling; their images are on the beasts and on the cattle: the things which you took about have become a weight to the tired beast.", "geneva": "Bel is bowed downe: Nebo is fallen: their idoles were vpon the beastes, and vpon the cattell: they which did beare you, were laden with a wearie burden.", "wycliffe": "Bel is brokun, Nabo is al to-brokun; her symylacris lijk to wielde beestis and werk beestis ben brokun; youre birthuns", "rotherham": "Bel, hath crouched, Nebo, is cowering, Their images, are delivered up to beast and to cattle,—The things ye carried about, are become a load, A burden, to the weary!", "darby": "Bel is bowed down, Nebo bendeth; their idols are upon the beasts, and upon the cattle: the things ye carried are laid on, a burden to the weary [beast].", "twenty": "", "jps": "Bel boweth down, Nebo stoopeth; their idols are upon the beasts, and upon the cattle; the things that ye carried about are made a load, a burden to the weary beast.", "acv": "Bel bows down, Nebo stoops, their idols are upon the beasts, and upon the cattle. The things that ye carried about are made a load, a burden to the weary beast.", "anderson": "", "haweis": "", "noyes": "Bel sinketh down; Nebo falleth; Their images are laid upon beasts and cattle; Those that ye once bore are packed upon them; A burden to the weary beast!", "webster": "Bel boweth down, Nebo stoopeth, their idols were upon the beasts, and upon the cattle: your loads [were] heavy; [they were] a burden to the weary [beast].", "vulgate": "conflatus est Bel contritus est Nabo facta sunt simulacra eorum bestiis et iumentis onera vestra gravi pondere usque ad lassitudinem;", "brenton": "Bel has fallen, Nabo is broken to pieces, their graven images are gone to the wild beasts and the cattle: ye take them packed up as a burden to the weary, exhausted, hungry, and at the same time helpless man;"}}, {"v": 2, "ref": "46:2", "o": "קָרְס֤וּ כָֽרְעוּ֙ יַחְדָּ֔ו לֹ֥א יָכְל֖וּ מַלֵּ֣ט מַשָּׂ֑א וְ/נַפְשָׁ֖/ם בַּ/שְּׁבִ֥י הָלָֽכָה", "en": {"kjv": "They stoop, they bow down together; they could not deliver the burden, but themselves are gone into captivity.", "web": "They stoop, they bow down together; they could not deliver the burden, but themselves have gone into captivity.", "bsb": "The gods cower; they crouch together, unable to relieve the burden; but they themselves go into captivity.", "asv": "They stoop, they bow down together; they could not deliver the burden, but themselves are gone into captivity.", "ylt": "They have stooped, they have bowed together, They have not been able to deliver the burden, And themselves into captivity have gone.", "dra": "They are consumed, and are broken together: they could not save him that carried them, and they themselves shall go into captivity.", "bbe": "They are bent down, they are falling together: they were not able to keep their images safe, but they themselves have been taken prisoner.", "geneva": "They are bowed downe, and fallen together: for they coulde not rid them of the burden, and their soule is gone into captiuitie.", "wycliffe": "with heuy charge `til to werynesse weren rotun, and ben al to-brokun togidere; tho miyten not saue the berere, and the soule of hem schal go in to caitifte.", "rotherham": "They have cowered they have crouched at once, And they cannot rescue the burden,—But their own soul, into captivity, hath departed.", "darby": "They bend, they are bowed down together; they could not deliver the burden, and themselves are gone into captivity.", "twenty": "", "jps": "They stoop, they bow down together, they could not deliver the burden; and themselves are gone into captivity.", "acv": "They stoop, they bow down together. They could not deliver the burden, but themselves are gone into captivity.", "anderson": "", "haweis": "", "noyes": "They sink down; they fall together; They cannot rescue the burden; They themselves go into captivity.", "webster": "They stoop, they bow down together; they could not deliver the burden, but themselves have gone into captivity.", "vulgate": "contabuerunt et contrita sunt simul non potuerunt salvare portantem et anima eorum in captivitatem ibit;", "brenton": "who will not be able to save themselves from war, but they themselves are led away captive."}}, {"v": 3, "ref": "46:3", "o": "שִׁמְע֤וּ אֵלַ/י֙ בֵּ֣ית יַעֲקֹ֔ב וְ/כָל שְׁאֵרִ֖ית בֵּ֣ית יִשְׂרָאֵ֑ל הַֽ/עֲמֻסִים֙ מִנִּי בֶ֔טֶן הַ/נְּשֻׂאִ֖ים מִנִּי רָֽחַם", "en": {"kjv": "Hearken unto me, O house of Jacob, and all the remnant of the house of Israel, which are borne by me from the belly, which are carried from the womb:", "web": "“Listen to me, house of Jacob, and all the remnant of the house of Israel, that have been borne from their birth, that have been carried from the womb;", "bsb": "“Listen to Me, O house of Jacob, all the remnant of the house of Israel, who have been sustained from the womb, carried along since birth.", "asv": "Hearken unto me, O house of Jacob, and all the remnant of the house of Israel, that have been borneby mefrom their birth, that have been carried from the womb;", "ylt": "Hearken unto Me, O house of Jacob, And all the remnant of Israel, Who are borne from the belly, Who are carried from the womb,", "dra": "Hearken unto me, O house of Jacob, all the remnant of the house of Israel who are carried by my bowels, are borne up by my womb.", "bbe": "Give ear to me, O family of Jacob, and all the rest of the people of Israel, who have been supported by me from their birth, and have been my care from their earliest days:", "geneva": "Heare ye me, O house of Iaakob, and all that remaine of the house of Israel, which are borne of me from the wombe, and brought vp of me from the birth.", "wycliffe": "The hous of Jacob, and al the residue of the hous of Israel, here ye me, whiche ben borun of my wombe, whiche ben borun of my wombe.", "rotherham": "Hearken unto me O house of Jacob, Even all the remnant of the house of Israel,—Who have been borne from birth, Who have been carried from nativity:", "darby": "Hearken unto me, house of Jacob, and all the remnant of the house of Israel, ye who have been borne from the belly, who have been carried from the womb:", "twenty": "", "jps": "Hearken unto Me, O house of Jacob, and all the remnant of the house of Israel, that are borne by Me from the birth, that are carried from the womb:", "acv": "Hearken to me, O house of Jacob, and all the remnant of the house of Israel, who have been borne by me from their birth, who have been carried from the womb.", "anderson": "", "haweis": "", "noyes": "Hearken to me, O house of Jacob, And all the remnant of the house of Israel; Ye that have been borne by me from your birth, That have been carried by me from your earliest breath!", "webster": "Hearken to me, O house of Jacob, and all the remnant of the house of Israel, which are borne [by me] from the birth, which are carried from the womb:", "vulgate": "audite me domus Iacob et omne residuum domus Israhel qui portamini a meo utero qui gestamini a mea vulva;", "brenton": "Hear me, O house of Jacob, and all the remnant of Israel, who are borne by me from the womb, and taught by me from infancy, even to old age:"}}, {"v": 4, "ref": "46:4", "o": "וְ/עַד זִקְנָה֙ אֲנִ֣י ה֔וּא וְ/עַד שֵיבָ֖ה אֲנִ֣י אֶסְבֹּ֑ל אֲנִ֤י עָשִׂ֨יתִי֙ וַ/אֲנִ֣י אֶשָּׂ֔א וַ/אֲנִ֥י אֶסְבֹּ֖ל וַ/אֲמַלֵּֽט", "en": {"kjv": "And even to your old age I am he; and even to hoar hairs will I carry you: I have made, and I will bear; even I will carry, and will deliver you.", "web": "and even to old age I am he, and even to gray hairs will I carry you. I have made, and I will bear; yes, I will carry, and will deliver.", "bsb": "Even to your old age, I will be the same, and I will bear you up when you turn gray. I have made you, and I will carry you; I will sustain you and deliver you.", "asv": "and even to old age I am he, and even to hoar hairs will I carry you; I have made, and I will bear; yea, I will carry, and will deliver.", "ylt": "Even to old age I am He, and to grey hairs I carry, I made, and I bear, yea, I carry and deliver.", "dra": "Even to your old age I am the same, and to your grey hairs I will carry you: I have made you, and I will bear: I will carry and will save.", "bbe": "Even when you are old I will be the same, and when you are grey-haired I will take care of you: I will still be responsible for what I made; yes, I will take you and keep you safe.", "geneva": "Therefore vnto olde age, I the same, euen I will beare you vntill the hoare heares: I haue made you: I will also beare you, and I will cary you and I will deliuer you.", "wycliffe": "Til to eelde Y my silf, and til to hoor heeris Y schal bere; Y made, and Y schal bere, and Y schal saue.", "rotherham": "Even unto old age, I, am, the same, And unto grey hairs, I, will bear the burden,—I have made and, I, will carry, Yea, I, will bear the burden and will deliver,", "darby": "Even to old age, I [am] HE, and unto hoary hairs I will carry [you]: It is I that have made, and I will bear, and I will carry, and will deliver.", "twenty": "", "jps": "Even to old age I am the same, and even to hoar hairs will I carry you; I have made, and I will bear; yea, I will carry, and will deliver.", "acv": "And even to old age I am he, and even to hoar hairs I will carry you. I have made, and I will bear, yea, I will carry, and will deliver.", "anderson": "", "haweis": "", "noyes": "Even to your old age I am the same; Even to hoar hairs I will carry you; I have done it, and I will still bear you; I will carry, and will deliver you.", "webster": "And [even] to [your] old age I [am] he; and [even] to hoary hairs will I carry [you]: I have made, and I will bear; even I will carry, and will deliver [you].", "vulgate": "usque ad senectam ego ipse et usque ad canos ego portabo ego feci et ego feram et ego portabo et salvabo;", "brenton": "I am he; and until ye shall have grown old, I am he: I bear you, I have made, and I will relieve, I will take up and save you."}}, {"v": 5, "ref": "46:5", "o": "לְ/מִ֥י תְדַמְי֖וּ/נִי וְ/תַשְׁו֑וּ וְ/תַמְשִׁל֖וּ/נִי וְ/נִדְמֶֽה", "en": {"kjv": "To whom will ye liken me, and make me equal, and compare me, that we may be like?", "web": "“To whom will you liken me, and make me equal, and compare me, that we may be like?", "bsb": "To whom will you liken Me or count Me equal? To whom will you compare Me, that we should be alike?", "asv": "To whom will ye liken me, and make me equal, and compare me, that we may be like?", "ylt": "To whom do ye liken Me, and make equal? And compare Me, that we may be like?", "dra": "To whom have you likened me, and made me equal, and compared me, and made me like?", "bbe": "Who in your eyes is my equal? or what comparison will you make with me?", "geneva": "To whom will ye make me like or make me equall, or copare me, that I should be like him?", "wycliffe": "To whom han ye licned me, and maad euene, and han comparisound me, and han maad lijk?", "rotherham": "To whom can ye liken me or make me equal? Or compare me, and we be like?", "darby": "To whom will ye liken me and make me equal, or compare me, that we may be like?", "twenty": "", "jps": "To whom will ye liken Me, and make Me equal, and compare Me, that we may be like?", "acv": "To whom will ye liken me, and make me equal, and compare me, that we may be alike?", "anderson": "", "haweis": "", "noyes": "To whom will ye liken me, and compare me? Yea, to whom will ye compare me, that we may be like?", "webster": "To whom will ye liken me, and make [me] equal, and compare me, that we may be like?", "vulgate": "cui adsimilastis me et adaequastis et conparastis me et fecistis similem;", "brenton": "To whom have ye compared me? see, consider, ye that go astray."}}, {"v": 6, "ref": "46:6", "o": "הַ/זָּלִ֤ים זָהָב֙ מִ/כִּ֔יס וְ/כֶ֖סֶף בַּ/קָּנֶ֣ה יִשְׁקֹ֑לוּ יִשְׂכְּר֤וּ צוֹרֵף֙ וְ/יַעֲשֵׂ֣/הוּ אֵ֔ל יִסְגְּד֖וּ אַף יִֽשְׁתַּחֲוּֽוּ", "en": {"kjv": "They lavish gold out of the bag, and weigh silver in the balance, and hire a goldsmith; and he maketh it a god: they fall down, yea, they worship.", "web": "Some pour out gold from the bag, and weigh silver in the balance. They hire a goldsmith, and he makes it a god. They fall down—yes, they worship.", "bsb": "They pour out their bags of gold and weigh out silver on scales; they hire a goldsmith to fashion it into a god, so they can bow down and worship.", "asv": "Such as lavish gold out of the bag, and weigh silver in the balance, they hire a goldsmith, and he maketh it a god; they fall down, yea, they worship.", "ylt": "--They are pouring out gold from a bag, And silver on the beam they weigh, They hire a refiner, and he maketh it a god, They fall down, yea, they bow themselves.", "dra": "You that contribute gold out of the bag, and weigh out silver in the scales: and hire a goldsmith to make a god: and they fall down and worship.", "bbe": "As for those who take gold out of a bag, and put silver in the scales, they give payment to a gold-worker, to make it into a god; they go down on their faces and give it worship.", "geneva": "They draw gold out of the bagge and weigh siluer in the balance, and hire a goldsmith to make a god of it, and they bowe downe, and worship it.", "wycliffe": "Whiche beren togidere gold fro the bagge, and peisen siluer with a balaunce, and hiren a goldsmyth to make a god, and thei fallen doun, and worschipen; thei berynge beren in schuldris,", "rotherham": "They who pour gold out of a purse, And who weigh silver in a balance,—Who hire a goldsmith that he may make it into a GOD, They adore, yea they bow down;", "darby": "— They lavish gold out of the bag, and weigh silver in the balance; they hire a goldsmith, and he maketh it agod: they fall down, yea, they worship.", "twenty": "", "jps": "Ye that lavish gold out of the bag, and weigh silver in the balance; ye that hire a goldsmith, that he make it a god, to fall down thereto, yea, to worship.", "acv": "Such as lavish gold out of the bag, and weigh silver in the balance, they hire a goldsmith, and he makes it a god. They fall down, yea, they worship.", "anderson": "", "haweis": "", "noyes": "They lavish gold out of the bag, And weigh silver in the balance; They hire a goldsmith, and he maketh it a god; They fall down, yea, they worship it.", "webster": "They lavish gold out of the bag, and weigh silver in the balance, [and] hire a goldsmith; and he maketh it a god: they fall down, yes, they worship.", "vulgate": "qui confertis aurum de sacculo et argentum statera ponderatis conducentes aurificem ut faciat deum et procidunt et adorant;", "brenton": "They that furnish gold out of a purse, and silver by weight, will weigh it in a scale, and they hire a goldsmith and make idols, and bow down, and worship them."}}, {"v": 7, "ref": "46:7", "o": "יִ֠שָּׂאֻ/הוּ עַל כָּתֵ֨ף יִסְבְּלֻ֜/הוּ וְ/יַנִּיחֻ֤/הוּ תַחְתָּי/ו֙ וְ/יַֽעֲמֹ֔ד מִ/מְּקוֹמ֖/וֹ לֹ֣א יָמִ֑ישׁ אַף יִצְעַ֤ק אֵלָי/ו֙ וְ/לֹ֣א יַעֲנֶ֔ה מִ/צָּרָת֖/וֹ לֹ֥א יוֹשִׁיעֶֽ/נּוּ", "en": {"kjv": "They bear him upon the shoulder, they carry him, and set him in his place, and he standeth; from his place shall he not remove: yea, one shall cry unto him, yet can he not answer, nor save him out of his trouble.", "web": "They bear it on the shoulder, they carry it, and set it in its place, and it stands, from its place it shall not move: yes, one may cry to it, yet it can not answer, nor save him out of his trouble.", "bsb": "They lift it to their shoulder and carry it along; they set it in its place, and there it stands, not budging from that spot. They cry out to it, but it does not answer; it saves no one from his troubles.", "asv": "They bear it upon the shoulder, they carry it, and set it in its place, and it standeth, from its place shall it not remove: yea, one may cry unto it, yet can it not answer, nor save him out of his trouble.", "ylt": "They lift him up on the shoulder, They carry him, and cause him to rest in his place, And he standeth, from his place he moveth not, Yea, one crieth unto him, and he answereth not, From his adversity he saveth him not.", "dra": "They bear him on their shoulders and carry him, and set him in his place, and he shall stand, and shall not stir out of his place. Yea, when they shall cry also unto him, he shall not hear: he shall not save them from tribulation.", "bbe": "They put him on their backs, and take him up, and put him in his fixed place, from which he may not be moved; if a man gives a cry for help to him, he is unable to give an answer, or get him out of his trouble.", "geneva": "They beare it vpon the shoulders: they carie him and set him in his place: so doeth he stand, and cannot remoue from his place. Though one crie vnto him, yet can he not answere, nor deliuer him out of his tribulation.", "wycliffe": "and settynge in his place; and he schal stonde, and schal not be mouyd fro his place; but also whanne thei crien to hym, he schal not here, and he schal not saue hem fro tribulacioun.", "rotherham": "They carry him about on the shoulder They bear the burden of him—and set him in his place that he may stand,—Out of his place, will he not move,—Though one even make outcry unto him, he will not answer, Out of one’s trouble, he will not save him.", "darby": "They bear him on the shoulder, they carry him, and set him in his place; there he standeth, he doth not remove from his place: yea, one crieth unto him, and he answereth not; he saveth him not out of his trouble.", "twenty": "", "jps": "He is borne upon the shoulder, he is carried, and set in his place, and he standeth, from his place he doth not remove; yea, though one cry unto him, he cannot answer, nor save him out of his trouble.", "acv": "They bear it upon the shoulder. They carry it, and set it in its place, and it stands. From its place it shall not remove. Yea, he may cry to it, yet it cannot answer, nor save him out of his trouble.", "anderson": "", "haweis": "", "noyes": "They lift him upon the shoulder, and carry him; They set him in his place, and there he standeth; From his place he moveth not; Yea, one may cry to him, yet doth he not answer, Nor save him out of his distress.", "webster": "They bear him upon the shoulder, they carry him, and set him in his place, and he standeth; from his place shall he not remove: yes, [one] shall cry to him, yet he cannot answer, nor save him out of his trouble.", "vulgate": "portant illud in umeris gestantes et ponentes in loco suo et stabit ac de loco suo non movebitur sed et cum clamaverint ad eum non audiet de tribulatione non salvabit eos;", "brenton": "They bear it upon the shoulder, and go; and if they put it upon its place, it remains, it cannot move: and whosoever shall cry to it, it cannot hear; it cannot save him from trouble."}}, {"v": 8, "ref": "46:8", "o": "זִכְרוּ זֹ֖את וְ/הִתְאֹשָׁ֑שׁוּ הָשִׁ֥יבוּ פוֹשְׁעִ֖ים עַל לֵֽב", "en": {"kjv": "Remember this, and shew yourselves men: bring it again to mind, O ye transgressors.", "web": "“Remember this, and show yourselves men; bring it again to mind, you transgressors.", "bsb": "Remember this and be brave; take it to heart, you transgressors!", "asv": "Remember this, and show yourselves men; bring it again to mind, O ye transgressors.", "ylt": "Remember this, and shew yourselves men, Turn it back, O transgressors, to the heart.", "dra": "Remember this, and be ashamed: return, ye transgressors, to the heart.", "bbe": "Keep this in mind and be shamed; let it come back to your memory, you sinners.", "geneva": "Remember this, and be ashamed: bring it againe to minde, O you transgressers.", "wycliffe": "Haue ye mynde of this, and be ye aschamed; ye trespassouris, go ayen to the herte.", "rotherham": "Remember ye this and shew yourselves men,—Bring it back, ye transgressors, to your minds;", "darby": "Remember this, and shew yourselves men; call it to mind, ye transgressors.", "twenty": "", "jps": "Remember this, and stand fast; bring it to mind, O ye transgressors.", "acv": "Remember this, and show yourselves men. Bring it again to mind, O ye transgressors.", "anderson": "", "haweis": "", "noyes": "Remember these things, and show yourselves men; Lay them to heart, ye apostates!", "webster": "Remember this, and show yourselves men: bring [it] again to mind, O ye transgressors.", "vulgate": "mementote istud et fundamini redite praevaricatores ad cor;", "brenton": "Remember ye these things, and groan: repent, ye that have gone astray, return in your heart;"}}, {"v": 9, "ref": "46:9", "o": "זִכְר֥וּ רִאשֹׁנ֖וֹת מֵ/עוֹלָ֑ם כִּ֣י אָנֹכִ֥י אֵל֙ וְ/אֵ֣ין ע֔וֹד אֱלֹהִ֖ים וְ/אֶ֥פֶס כָּמֽוֹ/נִי", "en": {"kjv": "Remember the former things of old: for I am God, and there is none else; I am God, and there is none like me,", "web": "Remember the former things of old: for I am God, and there is no one else; I am God, and there is none like me;", "bsb": "Remember what happened long ago, for I am God, and there is no other; I am God, and there is none like Me.", "asv": "Remember the former things of old: for I am God, and there is none else; I am God, and there is none like me;", "ylt": "Remember former things of old, For I am Mighty, and there is none else, God--and there is none like Me.", "dra": "Remember the former age, for I am God, and there is no God beside, neither is there the like to me:", "bbe": "Let the things which are past come to your memory: for I am God, and there is no other; I am God, and there is no one like me;", "geneva": "Remember the former things of old: for I am God, and there is none other God, and there is nothing like me,", "wycliffe": "Bithenke ye on the formere world, for Y am God, and no God is ouer me, nether is lijk me.", "rotherham": "Remember ye the things named in advance from age-past times,—For, I, am, The Mighty One, and there is none else, The Adorable and there is none like me!", "darby": "Remember the former things of old; for I [am]God, and there is none else; [I am]God, and there is none like me;", "twenty": "", "jps": "Remember the former things of old: that I am G-d, and there is none else; I am G-d, and there is none like Me;", "acv": "Remember the former things of old, for I am God, and there is none else. I am God, and there is none like me,", "anderson": "", "haweis": "", "noyes": "Remember the former things in ancient times! For I am God, and there is none else; I am God, and there is none like me.", "webster": "Remember the former things of old: for I [am] God, and [there is] none else; I [am] God, and [there is] none like me,", "vulgate": "recordamini prioris saeculi quoniam ego sum Deus et non est ultra Deus nec est similis mei;", "brenton": "and remember the former things that were of old: for I am God, and there is none other beside me,"}}, {"v": 10, "ref": "46:10", "o": "מַגִּ֤יד מֵֽ/רֵאשִׁית֙ אַחֲרִ֔ית וּ/מִ/קֶּ֖דֶם אֲשֶׁ֣ר לֹא נַעֲשׂ֑וּ אֹמֵר֙ עֲצָתִ֣/י תָק֔וּם וְ/כָל חֶפְצִ֖/י אֶעֱשֶֽׂה", "en": {"kjv": "Declaring the end from the beginning, and from ancient times the things that are not yet done, saying, My counsel shall stand, and I will do all my pleasure:", "web": "declaring the end from the beginning, and from ancient times things that are not yet done; saying, My counsel shall stand, and I will do all my pleasure;", "bsb": "I declare the end from the beginning, and ancient times from what is still to come. I say, ‘My purpose will stand, and all My good pleasure I will accomplish.’", "asv": "declaring the end from the beginning, and from ancient times things that are not yet done; saying, My counsel shall stand, and I will do all my pleasure;", "ylt": "Declaring from the beginning the latter end, And from of old that which hath not been done, Saying, `My counsel doth stand, And all My delight I do.'", "dra": "Who shew from the beginning the things that shall be at last, and from ancient times the things that as yet are not done, saying: My counsel shall stand, and all my will shall be done:", "bbe": "Making clear from the first what is to come, and from past times the things which have not so far come about; saying, My purpose is fixed, and I will do all my pleasure;", "geneva": "Which declare the last thing from the beginning: and from of olde, the things that were not done, saying, My counsell shall stand, and I will doe whatsoeuer I will.", "wycliffe": "And Y telle fro the bigynnyng the laste thing, and fro the bigynnyng tho thingis that ben not maad yit; and Y seie, My councel schal stonde, and al my wille schal be don.", "rotherham": "Declaring from the beginning, the latter end, And from olden time, that which had never been done,—Saying My purpose shall stand, and All my pleasure, will I perform;", "darby": "declaring the end from the beginning, and from ancient times the things that are not yet done, saying, My counsel shall stand, and I will do all my pleasure;", "twenty": "", "jps": "Declaring the end from the beginning, and from ancient times things that are not yet done; saying: 'My counsel shall stand, and all My pleasure will I do';", "acv": "declaring the end from the beginning, and from ancient times things that are not yet done, saying, My counsel shall stand, and I will do all my pleasure,", "anderson": "", "haweis": "", "noyes": "Declaring the end from the beginning; From ancient times the things that were not yet done; Saying, My purpose shall stand, And I will do all my pleasure;", "webster": "Declaring the end from the beginning, and from ancient times [the things] that are not [yet] done, saying, My counsel shall stand, and I will do all my pleasure:", "vulgate": "adnuntians ab exordio novissimum et ab initio quae necdum facta sunt dicens consilium meum stabit et omnis voluntas mea fiet;", "brenton": "telling beforehand the latter events before they come to pass, and they are accomplished together: and I said, all my counsel shall stand, and I will do all things that I have planned:"}}, {"v": 11, "ref": "46:11", "o": "קֹרֵ֤א מִ/מִּזְרָח֙ עַ֔יִט מֵ/אֶ֥רֶץ מֶרְחָ֖ק אִ֣ישׁ עצת/ו עֲצָתִ֑/י אַף דִּבַּ֨רְתִּי֙ אַף אֲבִיאֶ֔/נָּה יָצַ֖רְתִּי אַף אֶעֱשֶֽׂ/נָּה", "en": {"kjv": "Calling a ravenous bird from the east, the man that executeth my counsel from a far country: yea, I have spoken it, I will also bring it to pass; I have purposed it, I will also do it.", "web": "calling a ravenous bird from the east, the man of my counsel from a far country; yes, I have spoken, I will also bring it to pass; I have purposed, I will also do it.", "bsb": "I summon a bird of prey from the east, a man for My purpose from a far-off land. Truly I have spoken, and truly I will bring it to pass. I have planned it, and I will surely do it.", "asv": "calling a ravenous bird from the east, the man of my counsel from a far country; yea, I have spoken, I will also bring it to pass; I have purposed, I will also do it.", "ylt": "Calling from the east a ravenous bird, From a far land the man of My counsel, Yea, I have spoken, yea, I bring it in, I have formed it , yea, I do it.", "dra": "Who call a bird from the east, and from a far country the man of my own will, and I have spoken, and will bring it to pass: I have created, and I will do it. Hear me, O ye hardhearted, who are far from justice.", "bbe": "Sending for a bird of strong flight from the east, the man of my purpose from a far country; I have said it, and I will give effect to it; the thing designed by me will certainly be done.", "geneva": "I call a birde from the East, and the man of my counsell from farre: as I haue spoken, so will I bring it to passe: I haue purposed it, and I will doe it.", "wycliffe": "And Y clepe a brid fro the eest, and the man of my wille fro a ferr lond; and Y spak, and Y schal brynge that thing; Y haue maad of nouyt, and Y schal make that thing.", "rotherham": "Calling, From the East, a Bird of Prey, From a far country, the Man I intended,—Yea I have spoken I will also bring it to pass, I have planned, I will also do it.", "darby": "calling a bird of prey from the east, the man of my counsel from a far country. Yea, I have spoken, I will also bring it to pass; I have purposed it, I will also do it.", "twenty": "", "jps": "Calling a bird of prey from the east, the man of My counsel from a far country; yea, I have spoken, I will also bring it to pass, I have purposed, I will also do it.", "acv": "calling a ravenous bird from the east, the man of my counsel from a far country. Yea, I have spoken. I will also bring it to pass. I have purposed. I will also do it.", "anderson": "", "haweis": "", "noyes": "Calling from the East the eagle, The man that executeth my purpose from a far country; I have spoken it, I will also bring it to pass; I have purposed it, I will also do it.", "webster": "Calling a ravenous bird from the east, the man that executeth my counsel from a far country: yes, I have spoken [it], I will also bring it to pass; I have purposed [it], I will also perform it.", "vulgate": "vocans ab oriente avem et de terra longinqua virum voluntatis meae et locutus sum et adducam illud creavi et faciam illud;", "brenton": "calling a bird from the east, and from a land afar off, for the things which I have planned: I have spoken, and brought him; I have created and made him; I have brought him, and prospered his way."}}, {"v": 12, "ref": "46:12", "o": "שִׁמְע֥וּ אֵלַ֖/י אַבִּ֣ירֵי לֵ֑ב הָ/רְחוֹקִ֖ים מִ/צְּדָקָֽה", "en": {"kjv": "Hearken unto me, ye stouthearted, that are far from righteousness:", "web": "Listen to me, you stout-hearted, who are far from righteousness:", "bsb": "Listen to Me, you stubborn people, far removed from righteousness:", "asv": "Hearken unto me, ye stout-hearted, that are far from righteousness:", "ylt": "Hearken unto Me, ye mighty in heart, Who are far from righteousness.", "dra": "I have brought my justice near, it shall not be afar off: and my salvation shall not tarry. I will give salvation in Sion, and my glory in Israel.", "bbe": "Give ear to me, you feeble-hearted, who have no faith in my righteousness:", "geneva": "Heare me, ye stubburne hearted, that are farre from iustice.", "wycliffe": "Ye of hard herte, here me, that ben fer fro riytfulnesse.", "rotherham": "Hearken unto me, Ye valiant of heart,—Who are far away from righteousness:", "darby": "Hearken unto me, ye stout-hearted, that are far from righteousness:", "twenty": "", "jps": "Hearken unto Me, ye stout-hearted, that are far from righteousness:", "acv": "Hearken to me, ye stout-hearted, who are far from righteousness:", "anderson": "", "haweis": "", "noyes": "Hearken to me, ye stubborn-hearted, That are far from deliverance!", "webster": "Hearken to me, ye stout-hearted, that [are] far from righteousness:", "vulgate": "audite me duro corde qui longe estis a iustitia;", "brenton": "Hearken to me, ye senseless ones, that are far from righteousness:"}}, {"v": 13, "ref": "46:13", "o": "קֵרַ֤בְתִּי צִדְקָתִ/י֙ לֹ֣א תִרְחָ֔ק וּ/תְשׁוּעָתִ֖/י לֹ֣א תְאַחֵ֑ר וְ/נָתַתִּ֤י בְ/צִיּוֹן֙ תְּשׁוּעָ֔ה לְ/יִשְׂרָאֵ֖ל תִּפְאַרְתִּֽ/י", "en": {"kjv": "I bring near my righteousness; it shall not be far off, and my salvation shall not tarry: and I will place salvation in Zion for Israel my glory.", "web": "I bring near my righteousness, it shall not be far off, and my salvation shall not wait; and I will place salvation in Zion for Israel my glory.", "bsb": "I am bringing My righteousness near; it is not far away, and My salvation will not be delayed. I will grant salvation to Zion and adorn Israel with My splendor.", "asv": "I bring near my righteousness, it shall not be far off, and my salvation shall not tarry; and I will place salvation in Zion for Israel my glory.", "ylt": "I have brought near My righteousness, It is not far off, And My salvation--it doth not tarry, And I have given in Zion salvation, To Israel My glory!", "dra": "", "bbe": "My righteousness is near, it is not far off; salvation will come quickly; and I will make Zion free, and give Israel my glory.", "geneva": "I bring neere my iustice: it shall not be farre off, and my saluation shall not tarie: for I wil giue saluation in Zion, and my glory vnto Israel.", "wycliffe": "Y made nyy myn riytfulnesse, it schal not be drawun afer, and myn helthe shal not tarie; Y schal yyue helthe in Sion, and my glorie in Israel.", "rotherham": "I have brought near my righteousness. It shall not be far away, And my deliverance, shall not linger,—But I will give In Zion, deliverance, To Israel, my glory.", "darby": "I bring near my righteousness; it shall not be far off, and my salvation shall not delay; and I will give salvation in Zion, [and] unto Israel my glory.", "twenty": "", "jps": "I bring near My righteousness, it shall not be far off, and My salvation shall not tarry; and I will place salvation in Zion for Israel My glory.", "acv": "I bring near my righteousness. It shall not be far off. And my salvation shall not tarry, and I will place salvation in Zion for Israel my glory.", "anderson": "", "haweis": "", "noyes": "I have brought near my deliverance; it is not far off; My salvation shall not tarry; I will give to Zion salvation, To Israel, my glory.", "webster": "I bring near my righteousness; it shall not be far off, and my salvation shall not delay: and I will place salvation in Zion for Israel my glory.", "vulgate": "prope feci iustitiam meam non elongabitur et salus mea non morabitur dabo in Sion salutem et Israheli gloriam meam;", "brenton": "I have brought near my righteousness, and I will not be slow with the salvation that is from me: I have given salvation in Sion to Israel for glory."}}]}, {"c": 47, "verses": [{"v": 1, "ref": "47:1", "o": "רְדִ֣י וּ/שְׁבִ֣י עַל עָפָ֗ר בְּתוּלַת֙ בַּת בָּבֶ֔ל שְׁבִי לָ/אָ֥רֶץ אֵין כִּסֵּ֖א בַּת כַּשְׂדִּ֑ים כִּ֣י לֹ֤א תוֹסִ֨יפִי֙ יִקְרְאוּ לָ֔/ךְ רַכָּ֖ה וַ/עֲנֻגָּֽה", "en": {"kjv": "Come down, and sit in the dust, O virgin daughter of Babylon, sit on the ground: there is no throne, O daughter of the Chaldeans: for thou shalt no more be called tender and delicate.", "web": "“Come down, and sit in the dust, virgin daughter of Babylon; sit on the ground without a throne, daughter of the Chaldeans: for you shall no more be called tender and delicate.", "bsb": "“Go down and sit in the dust, O Virgin Daughter of Babylon. Sit on the ground without a throne, O Daughter of Chaldea! For you will no longer be called tender or delicate.", "asv": "Come down, and sit in the dust, O virgin daughter of Babylon; sit on the ground without a throne, O daughter of the Chaldeans: for thou shalt no more be called tender and delicate.", "ylt": "Come down, and sit on the dust, O virgin daughter of Babylon, Sit on the earth, there is no throne, O daughter of the Chaldeans, For no more do they cry to thee, `O tender and delicate one.'", "dra": "Come down, sit in the dust, O virgin daughter of Babylon, sit on the ground: there is no throne for the daughter of the Chaldeans, for thou shalt no more be called delicate and tender.", "bbe": "Come and take your seat in the dust, O virgin daughter of Babylon; come down from your seat of power, and take your place on the earth, O daughter of the Chaldaeans: for you will never again seem soft and delicate.", "geneva": "Come downe and sit in the dust: O virgine, daughter Babel, sit on the ground: there is no throne, O daughter of the Chaldeans: for thou shalt no more be called, Tender and delicate.", "wycliffe": "Thou virgyn, the douytir Babiloyne, go doun, sitte thou in dust, sitte thou in erthe; a kyngis seete is not to the douyter of Caldeis, for thou schalt no more be clepid soft and tendir.", "rotherham": "Down—and sit in the dust, O virgin Daughter of Babylon, Sit on the ground—throneless, Daughter of the Chaldeans; For thou shalt no more be called Tender and Dainty.", "darby": "Come down and sit in the dust, virgin-daughter of Babylon! Sit on the ground, — [there is] no throne, O daughter of the Chaldeans; for thou shalt no more be called tender and delicate.", "twenty": "", "jps": "Come down, and sit in the dust, O virgin daughter of Babylon, sit on the ground without a throne, O daughter of the Chaldeans; for thou shalt no more be called tender and delicate.", "acv": "Come down, and sit in the dust, O virgin daughter of Babylon. Sit on the ground without a throne, O daughter of the Chaldeans. For thou shall no more be called tender and delicate.", "anderson": "", "haweis": "", "noyes": "Come down, and sit in the dust, O virgin, daughter of Babylon! Sit on the ground without a throne, O daughter of the Chaldaeans! For thou shalt no longer be called the tender and delicate!", "webster": "Come down, and sit in the dust, O virgin daughter of Babylon, sit on the ground: [there is] no throne, O daughter of the Chaldeans: for thou shalt no more be called tender and delicate.", "vulgate": "descende sede in pulverem virgo filia Babylon sede in terra non est solium filiae Chaldeorum quia ultra non vocaberis mollis et tenera;", "brenton": "Come down, sit on the ground, O virgin daughter of Babylon: sit on the ground, O daughter of the Chaldeans: for thou shalt no more be called tender and luxurious."}}, {"v": 2, "ref": "47:2", "o": "קְחִ֥י רֵחַ֖יִם וְ/טַ֣חֲנִי קָ֑מַח גַּלִּ֨י צַמָּתֵ֧/ךְ חֶשְׂפִּי שֹׁ֛בֶל גַּלִּי שׁ֖וֹק עִבְרִ֥י נְהָרֽוֹת", "en": {"kjv": "Take the millstones, and grind meal: uncover thy locks, make bare the leg, uncover the thigh, pass over the rivers.", "web": "Take the millstones, and grind meal; remove your veil, strip off the train, uncover the leg, pass through the rivers.", "bsb": "Take millstones and grind flour; remove your veil; strip off your skirt, bare your thigh, and wade through the streams.", "asv": "Take the millstones, and grind meal; remove thy veil, strip off the train, uncover the leg, pass through the rivers.", "ylt": "Take millstones, and grind flour, Remove thy veil, draw up the skirt, Uncover the leg, pass over the floods.", "dra": "Take a millstone and grind meal: uncover thy shame, strip thy shoulder, make bare thy legs, pass over the rivers.", "bbe": "Take the crushing-stones and get the meal crushed: take off your veil, put away your robe, let your legs be uncovered, go through the rivers.", "geneva": "Take the mill stones, and grinde meale: loose thy lockes: make bare the feete: vncouer the legge, and passe through the floods.", "wycliffe": "Take thou a queerne stoon, and grynde thou mele; make thou nakid thi filthe, diskeuere the schuldur, schewe the hippis, passe thou floodis.", "rotherham": "Take millstones, and grind meal,—Put back thy veil—tuck up thy train Bare the leg, wade through streams:", "darby": "Take the millstones, and grind meal; remove thy veil, lift up the train, uncover the leg, pass over rivers:", "twenty": "", "jps": "Take the millstones, and grind meal; remove thy veil, strip off the train, uncover the leg, pass through the rivers.", "acv": "Take the millstones, and grind meal. Remove thy veil, strip off the train, uncover the leg, pass through the rivers.", "anderson": "", "haweis": "", "noyes": "Take the mill-stones and grind meal; Raise thy veil, lift up thy train; Make bare the leg, wade through the streams!", "webster": "Take the millstones, and grind meal: uncover thy locks, make bare the leg, uncover the thigh, pass over the rivers.", "vulgate": "tolle molam et mole farinam denuda turpitudinem tuam discoperi umerum revela crus transi flumina;", "brenton": "Take a millstone, grind meal: remove thy veil, uncover thy white hairs, make bare the leg, pass through the rivers."}}, {"v": 3, "ref": "47:3", "o": "תִּגָּל֙ עֶרְוָתֵ֔/ךְ גַּ֥ם תֵּרָאֶ֖ה חֶרְפָּתֵ֑/ךְ נָקָ֣ם אֶקָּ֔ח וְ/לֹ֥א אֶפְגַּ֖ע אָדָֽם", "en": {"kjv": "Thy nakedness shall be uncovered, yea, thy shame shall be seen: I will take vengeance, and I will not meet thee as a man.", "web": "Your nakedness shall be uncovered, yes, your shame shall be seen: I will take vengeance, and will spare no man.”", "bsb": "Your nakedness will be uncovered and your shame will be exposed. I will take vengeance; I will spare no one.”", "asv": "Thy nakedness shall be uncovered, yea, thy shame shall be seen: I will take vengeance, and will spare no man.", "ylt": "Revealed is thy nakedness, yea, seen is thy reproach, Vengeance I take, and I meet not a man.", "dra": "Thy nakedness shall be discovered, and thy shame shall be seen: I will take vengeance, and no man shall resist me.", "bbe": "The shame of your unclothed condition will be seen by all: I will give punishment without mercy,", "geneva": "Thy filthinesse shall be discouered, and thy shame shall be seene: I will take vengeance, and I will not meete thee as a man.", "wycliffe": "Thi schame schal be schewid, and thi schenschipe schal be seen; Y schal take veniaunce, and no man schal ayenstonde me.", "rotherham": "Bared shall be thy shame, Yea seen thy reproach,—An avenging, will I take, And will accept no son of earth.", "darby": "thy nakedness shall be uncovered, yea, thy shame shall be seen. I will take vengeance, and I will meet none [to stay me]. ...", "twenty": "", "jps": "Thy nakedness shall be uncovered, yea, thy shame shall be seen; I will take vengeance, and will let no man intercede.", "acv": "Thy nakedness shall be uncovered, yea, thy shame shall be seen. I will take vengeance, and will spare no man.", "anderson": "", "haweis": "", "noyes": "Thy nakedness shall be uncovered, And thy shame shall be seen. I will take vengeance; I will make peace with none.", "webster": "Thy nakedness shall be uncovered, yes, thy shame shall be seen: I will take vengeance, and I will not meet [thee as] a man.", "vulgate": "revelabitur ignominia tua et videbitur obprobrium tuum ultionem capiam et non resistet mihi homo;", "brenton": "Thy shame shall be uncovered, thy reproaches shall be brought to light: I will exact of thee due vengeance, I will no longer deliver thee to men."}}, {"v": 4, "ref": "47:4", "o": "גֹּאֲלֵ֕/נוּ יְהוָ֥ה צְבָא֖וֹת שְׁמ֑/וֹ קְד֖וֹשׁ יִשְׂרָאֵֽל", "en": {"kjv": "As for our redeemer, the Lord of hosts is his name, the Holy One of Israel.", "web": "Our Redeemer, Yahweh of Armies is his name, the Holy One of Israel.", "bsb": "Our Redeemer—the LORD of Hosts is His name— is the Holy One of Israel.", "asv": "Our Redeemer, Jehovah of hosts is his name, the Holy One of Israel.", "ylt": "Our redeemer is Jehovah of Hosts, His name is the Holy One of Israel.", "dra": "Our redeemer, the Lord of hosts is his name, the Holy One of Israel.", "bbe": "Says the Lord who takes up our cause; the Lord of armies is his name, the Holy One of Israel.", "geneva": "Our redeemer, the Lord of hostes is his Name, the holy one of Israel.", "wycliffe": "Oure ayen biere, the Lord of oostis is his name, the hooli of Israel.", "rotherham": "Our Redeemer, Yahweh of hosts, is his name! The Holy One of Israel.", "darby": "Our Redeemer, Jehovah of hosts is his name, the Holy One of Israel. ...", "twenty": "", "jps": "Our Redeemer, HaShem of hosts is His name, The Holy One of Israel.", "acv": "Our Redeemer, Jehovah of hosts is his name, the Holy One of Israel.", "anderson": "", "haweis": "", "noyes": "Our Redeemer, Jehovah of hosts is his name, The Holy One of Israel.", "webster": "[As for] our Redeemer, the LORD of hosts [is] his name, the Holy One of Israel.", "vulgate": "redemptor noster Dominus exercituum nomen illius Sanctus Israhel;", "brenton": "Thy deliverer is the Lord of hosts, the Holy One of Israel is his name."}}, {"v": 5, "ref": "47:5", "o": "שְׁבִ֥י דוּמָ֛ם וּ/בֹ֥אִי בַ/חֹ֖שֶׁךְ בַּת כַּשְׂדִּ֑ים כִּ֣י לֹ֤א תוֹסִ֨יפִי֙ יִקְרְאוּ לָ֔/ךְ גְּבֶ֖רֶת מַמְלָכֽוֹת", "en": {"kjv": "Sit thou silent, and get thee into darkness, O daughter of the Chaldeans: for thou shalt no more be called, The lady of kingdoms.", "web": "“Sit in silence, and go into darkness, daughter of the Chaldeans; for you shall no more be called the mistress of kingdoms.", "bsb": "“Sit in silence and go into darkness, O Daughter of Chaldea. For you will no longer be called the queen of kingdoms.", "asv": "Sit thou silent, and get thee into darkness, O daughter of the Chaldeans; for thou shalt no more be called The mistress of kingdoms.", "ylt": "Sit silent, and go into darkness, O daughter of the Chaldeans, For no more do they cry to thee, `Mistress of kingdoms.'", "dra": "Sit thou silent, and get thee into darkness, O daughter of the Chaldeans: for thou shalt no more be called the lady of kingdoms.", "bbe": "Be seated in the dark without a word, O daughter of the Chaldaeans: for you will no longer be named, The Queen of Kingdoms.", "geneva": "Sit still, and get thee into darkenesse, O daughter of the Chaldeas: for thou shalt no more be called, The ladie of kingdomes.", "wycliffe": "Douyter of Caldeis, sitte thou, be thou stille, and entre in to derknessis, for thou schalt no more be clepid the ladi of rewmes.", "rotherham": "Sit silent, and get into darkness, Daughter of the Chaldeans! For thou shalt no more be called Mistress of Kingdoms.", "darby": "Sit silent, and get thee into darkness, daughter of the Chaldeans; for thou shalt no more be called, Mistress of kingdoms.", "twenty": "", "jps": "Sit thou silent, and get thee into darkness, O daughter of the Chaldeans; for thou shalt no more be called the mistress of kingdoms.", "acv": "Sit thou silent, and get thee into darkness, O daughter of the Chaldeans, for thou shall no more be called The mistress of kingdoms.", "anderson": "", "haweis": "", "noyes": "Sit thou in silence; go into darkness, O daughter of the Chaldaeans! For thou shalt no more be called the mistress of kingdoms.", "webster": "Sit thou silent, and get thee into darkness, O daughter of the Chaldeans: for thou shalt no more be called, The lady of kingdoms.", "vulgate": "sede tace et intra in tenebras filia Chaldeorum quia non vocaberis ultra domina regnorum;", "brenton": "Sit thou down pierced with woe, go into darkness, O daughter of the Chaldeans: thou shalt no more be called the strength of a kingdom."}}, {"v": 6, "ref": "47:6", "o": "קָצַ֣פְתִּי עַל עַמִּ֗/י חִלַּ֨לְתִּי֙ נַחֲלָתִ֔/י וָ/אֶתְּנֵ֖/ם בְּ/יָדֵ֑/ךְ לֹא שַׂ֤מְתְּ לָ/הֶם֙ רַחֲמִ֔ים עַל זָקֵ֕ן הִכְבַּ֥דְתְּ עֻלֵּ֖/ךְ מְאֹֽד", "en": {"kjv": "I was wroth with my people, I have polluted mine inheritance, and given them into thine hand: thou didst shew them no mercy; upon the ancient hast thou very heavily laid thy yoke.", "web": "I was angry with my people, I profaned my inheritance, and gave them into your hand: you showed them no mercy; on the aged you have very heavily laid your yoke.", "bsb": "I was angry with My people; I profaned My heritage, and I placed them under your control. You showed them no mercy; even on the elderly you laid a most heavy yoke.", "asv": "I was wroth with my people, I profaned mine inheritance, and gave them into thy hand: thou didst show them no mercy; upon the aged hast thou very heavily laid thy yoke.", "ylt": "I have been wroth against My people, I have polluted Mine inheritance And I give them into thy hand, Thou hast not appointed for them mercies, On the aged thou hast made thy yoke very heavy,", "dra": "I was angry with my people, I have polluted my inheritance, and have given them into thy hand: thou hast shewn no mercy to them: upon the ancient thou hast laid thy yoke exceeding heavy.", "bbe": "I was angry with my people, I put shame on my heritage, and gave them into your hands: you had no mercy on them; you put a cruel yoke on those who were old;", "geneva": "I was wroth with my people: I haue polluted mine inheritance, and giuen them into thine had: thou diddest shew them no mercy, but thou didest lay thy very heauy yoke vpon the ancient.", "wycliffe": "I was wrooth on my puple, Y defoulid myn eritage, and Y yaf hem in thin hond, and thou settidist not mercies to hem; thou madist greuouse the yok greetli on an eld man,", "rotherham": "I had been provoked with my people, Had profaned mine inheritance, And given them into thy hand, …Thou shewedst them no compassion, Upon the elder, madest thou very heavy thy yoke.", "darby": "I was wroth with my people, I polluted mine inheritance, and gave them into thy hand: thou didst shew them no mercy; upon the aged didst thou very heavily lay thy yoke;", "twenty": "", "jps": "I was wroth with My people, I profaned Mine inheritance, and gave them into thy hand; thou didst show them no mercy; upon the aged hast thou very heavily laid thy yoke.", "acv": "I was angry with my people. I profaned my inheritance, and gave them into thy hand. Thou showed them no mercy. Upon the aged thou have laid thy yoke very heavily.", "anderson": "", "haweis": "", "noyes": "I was angry with my people; I profaned my inheritance, And gave them into thy hand; Thou didst show them no mercy; Even upon the aged didst thou lay a very grievous yoke.", "webster": "I was wroth with my people, I have polluted my inheritance, and given them into thy hand: thou didst show them no mercy; upon the ancient hast thou very heavily laid thy yoke.", "vulgate": "iratus sum super populum meum contaminavi hereditatem meam et dedi eos in manu tua non posuisti eis misericordias super senem adgravasti iugum tuum valde;", "brenton": "I have been provoked with my people; thou hast defiled mine inheritance: I gave them into thy hand, but thou didst not extend mercy to them: thou madest the yoke of the aged man very heavy,"}}, {"v": 7, "ref": "47:7", "o": "וַ/תֹּ֣אמְרִ֔י לְ/עוֹלָ֖ם אֶהְיֶ֣ה גְבָ֑רֶת עַ֣ד לֹא שַׂ֥מְתְּ אֵ֨לֶּה֙ עַל לִבֵּ֔/ךְ לֹ֥א זָכַ֖רְתְּ אַחֲרִיתָֽ/הּ", "en": {"kjv": "And thou saidst, I shall be a lady for ever: so that thou didst not lay these things to thy heart, neither didst remember the latter end of it.", "web": "You said, ‘I shall be a mistress forever;’ so that you did not lay these things to your heart, nor did you remember the latter end of it.", "bsb": "You said, ‘I will be queen forever.’ You did not take these things to heart or consider their outcome.", "asv": "And thou saidst, I shall be mistress for ever; so that thou didst not lay these things to thy heart, neither didst remember the latter end thereof.", "ylt": "And thou sayest, `To the age I am mistress,' While thou hast not laid these things to thy heart, Thou hast not remembered the latter end of it.", "dra": "And thou hast said: I shall be a lady for ever: thou hast not laid these things to thy heart, neither hast thou remembered thy latter end.", "bbe": "And you said, I will be a queen for ever: you did not give attention to these things, and did not keep in mind what would come after.", "geneva": "And thou saidest, I shall be a ladie for euer, so that thou diddest not set thy mind to these things, neither diddest thou remember ye latter end therof.", "wycliffe": "and thou seidist, With outen ende Y schal be ladi; thou puttidist not these thingis on thin herte, nether thou bithouytist on thi laste thing.", "rotherham": "And thou saidst, Unto times age-abiding, shall I be Mistress,—Insomuch that thou laidst not these things to thy heart, Didst not keep in mind the issue thereof,", "darby": "and thou saidst, I shall be a mistress for ever; so that thou didst not take these things to heart, thou didst not remember the end thereof.", "twenty": "", "jps": "And thou saidst: 'For ever shall I be mistress'; so that thou didst not lay these things to thy heart, neither didst remember the end thereof.", "acv": "And thou said, I shall be mistress forever, so that thou did not lay these things to thy heart, nor remembered the latter end of it.", "anderson": "", "haweis": "", "noyes": "Thou saidst, \"I shall be mistress forever\"; So that thou didst not lay these things to thy heart, Nor consider what would be the end of them.", "webster": "And thou saidst, I shall be a lady for ever: [so] that thou didst not lay these [things] to thy heart, neither didst remember the latter end of it.", "vulgate": "et dixisti in sempiternum ero domina non posuisti haec super cor tuum neque recordata es novissimi tui;", "brenton": "and saidst, I shall be a princess for ever: thou didst not perceive these things in thine heart, nor didst thou remember the latter end."}}, {"v": 8, "ref": "47:8", "o": "וְ/עַתָּ֞ה שִׁמְעִי זֹ֤את עֲדִינָה֙ הַ/יּוֹשֶׁ֣בֶת לָ/בֶ֔טַח הָ/אֹֽמְרָה֙ בִּ/לְבָ֔בָ/הּ אֲנִ֖י וְ/אַפְסִ֣/י ע֑וֹד לֹ֤א אֵשֵׁב֙ אַלְמָנָ֔ה וְ/לֹ֥א אֵדַ֖ע שְׁכֽוֹל", "en": {"kjv": "Therefore hear now this, thou that art given to pleasures, that dwellest carelessly, that sayest in thine heart, I am, and none else beside me; I shall not sit as a widow, neither shall I know the loss of children:", "web": "“Now therefore hear this, you who are given to pleasures, who sit securely, who say in your heart, ‘I am, and there is no one else besides me; I shall not sit as a widow, neither shall I know the loss of children:’", "bsb": "So now hear this, O lover of luxury who sits securely, who says to herself, ‘I am, and there is none besides me. I will never be a widow or know the loss of children.’", "asv": "Now therefore hear this, thou that art given to pleasures, that sittest securely, that sayest in thy heart, I am, and there is none else besides me; I shall not sit as a widow, neither shall I know the loss of children:", "ylt": "And now, hear this, O luxurious one, Who is sitting confidently--Who is saying in her heart, `I am , and none else, I sit not a widow, nor know bereavement.'", "dra": "And now hear these things, thou that art delicate, and dwellest confidently, that sayest in thy heart: I am, and there is none else besides me: I shall not sit as a widow, and I shall not know barrenness.", "bbe": "So now take note of this, you who are given up to pleasure, living without fear of evil, saying in your heart, I am, and there is no one like me; I will never be a widow, or have my children taken from me.", "geneva": "Therefore nowe heare, thou that art giuen to pleasures, and dwellest carelesse, Shee sayeth in her heart, I am and none els: I shall not sit as a widowe, neither shall knowe the losse of children.", "wycliffe": "And now, thou delicat, and dwellynge tristili, here these thingis, which seist in thin herte, Y am, and outakun me ther is no more; Y schal not sitte widewe, and Y schal not knowe bareynesse.", "rotherham": "Now, therefore hear this, Thou Lady of pleasure Who dwelleth securely, Who saith in her heart,—I, [am], and there is no one besides, I shall not sit a widow, Nor know loss of children.", "darby": "And now hear this, thou voluptuous one, that dwellest carelessly, that sayest in thy heart, It is I, and there is none but me; I shall not sit as a widow, neither shall I know loss of children:", "twenty": "", "jps": "Now therefore hear this, thou that art given to pleasures, that sittest securely, that sayest in thy heart: 'I am, and there is none else beside me; I shall not sit as a widow, neither shall I know the loss of children';", "acv": "Now therefore hear this, thou who are given to pleasures, who sit securely, who say in thy heart, I am, and there is none else besides me. I shall not sit as a widow, nor shall I know the loss of sons.", "anderson": "", "haweis": "", "noyes": "But hear thou this, thou that art given to pleasure! That sittest in security, And sayest in thy heart, \"I am, and there is none besides me; I shall not be a widow, Nor see myself childless!\"", "webster": "Therefore hear now this, [thou that art] given to pleasures, that dwellest carelessly, that sayest in thy heart, I [am], and none else besides me; I shall not sit [as] a widow, neither shall I know the loss of children:", "vulgate": "et nunc audi haec delicata et habitans confidenter quae dicis in corde tuo ego sum et non est praeter me amplius non sedebo vidua et ignorabo sterilitatem;", "brenton": "But now hear these words, thou luxurious one, who art the one that sits at ease, that is secure, that says in her heart, I am, and there is not another; I shall not sit a widow, neither shall I know bereavement."}}, {"v": 9, "ref": "47:9", "o": "וְ/תָבֹאנָה֩ לָּ֨/ךְ שְׁתֵּי אֵ֥לֶּה רֶ֛גַע בְּ/י֥וֹם אֶחָ֖ד שְׁכ֣וֹל וְ/אַלְמֹ֑ן כְּ/תֻמָּ/ם֙ בָּ֣אוּ עָלַ֔יִ/ךְ בְּ/רֹ֣ב כְּשָׁפַ֔יִ/ךְ בְּ/עָצְמַ֥ת חֲבָרַ֖יִ/ךְ מְאֹֽד", "en": {"kjv": "But these two things shall come to thee in a moment in one day, the loss of children, and widowhood: they shall come upon thee in their perfection for the multitude of thy sorceries, and for the great abundance of thine enchantments.", "web": "but these two things shall come to you in a moment in one day, the loss of children, and widowhood; in their full measure shall they come on you, in the multitude of your sorceries, and the great abundance of your enchantments.", "bsb": "These two things will overtake you in a moment, in a single day: loss of children, and widowhood. They will come upon you in full measure, in spite of your many sorceries and the potency of your spells.", "asv": "but these two things shall come to thee in a moment in one day, the loss of children, and widowhood; in their full measure shall they come upon thee, in the multitude of thy sorceries, and the great abundance of thine enchantments.", "ylt": "And come in to thee do these two things, In a moment, in one day, childlessness and widowhood, According to their perfection they have come upon thee, In the multitude of thy sorceries, In the exceeding might of thy charms.", "dra": "These two things shall come upon thee suddenly in one day, barrenness and widowhood. All things are come upon thee, because of the multitude of thy sorceries, and for the great hardness of thy enchanters.", "bbe": "But these two things will come on you suddenly in one day, the loss of children and of husband: in full measure they will come on you, for all your secret arts, and all your wonders.", "geneva": "But these two thinges shall come to thee suddenly on one day, the losse of children and widowhoode: they shall come vpon thee in their perfection, for the multitude of thy diuinations, and for the great abundance of thine inchanters.", "wycliffe": "These twei thingis, bareynesse and widewhod schulen come to thee sudenli in o dai; alle thingis camen on thee for the multitude of thi witchecraftis, and for the greet hardnesse of thin enchauntours, ether tregetours.", "rotherham": "Yet shall there come to thee—both these, in a moment, in one day, Loss of children and widowhood,—To their full, have they come on thee, Spite of the mass of thine incantations, Spite of the great throng of thy spells.", "darby": "yet these two things shall come upon thee in a moment, in one day, loss of children and widowhood; they shall come upon thee in full measure for the multitude of thy sorceries, for the great abundance of thine enchantments.", "twenty": "", "jps": "But these two things shall come to thee in a moment in one day, the loss of children, and widow-hood; in their full measure shall they come upon thee, for the multitude of thy sorceries, and the great abundance of thine enchantments.", "acv": "But these two things shall come to thee in a moment in one day: the loss of sons, and widowhood. In their full measure they shall come upon thee, in the multitude of thy sorceries, and the great abundance of thine enchantments.", "anderson": "", "haweis": "", "noyes": "Behold, both these things shall come upon thee suddenly, in one day, Loss of children, and widowhood; In full measure shall they come upon thee, In spite of thy many sorceries, And the great abundance of thy enchantments.", "webster": "But these two [things] shall come to thee in a moment in one day, the loss of children, and widowhood: they shall come upon thee in their perfection, for the multitude of thy sorceries, [and] for the great abundance of thy enchantments.", "vulgate": "venient tibi duo haec subito in die una sterilitas et viduitas universa venerunt super te propter multitudinem maleficiorum tuorum et propter duritiam incantatorum tuorum vehementem;", "brenton": "But now these two things shall come upon thee suddenly in one day, the loss of children and widowhood shall come suddenly upon thee, for thy sorcery, for the strength of thine enchantments,"}}, {"v": 10, "ref": "47:10", "o": "וַ/תִּבְטְחִ֣י בְ/רָעָתֵ֗/ךְ אָמַרְתְּ֙ אֵ֣ין רֹאָ֔/נִי חָכְמָתֵ֥/ךְ וְ/דַעְתֵּ֖/ךְ הִ֣יא שׁוֹבְבָ֑תֶ/ךְ וַ/תֹּאמְרִ֣י בְ/לִבֵּ֔/ךְ אֲנִ֖י וְ/אַפְסִ֥/י עֽוֹד", "en": {"kjv": "For thou hast trusted in thy wickedness: thou hast said, None seeth me. Thy wisdom and thy knowledge, it hath perverted thee; and thou hast said in thine heart, I am, and none else beside me.", "web": "For you have trusted in your wickedness; you have said, No one sees me; your wisdom and your knowledge, it has perverted you, and you have said in your heart, I am, and there is no one else besides me.", "bsb": "You were secure in your wickedness; you said, ‘No one sees me.’ Your wisdom and knowledge led you astray; you told yourself, ‘I am, and there is none besides me.’", "asv": "For thou hast trusted in thy wickedness; thou hast said, None seeth me; thy wisdom and thy knowledge, it hath perverted thee, and thou hast said in thy heart, I am, and there is none else besides me.", "ylt": "And thou art confident in thy wickedness, Thou hast said, `There is none seeing me,' Thy wisdom and thy knowledge, It is turning thee back, And thou sayest in thy heart, `I am , and none else.'", "dra": "And thou hast trusted in thy wickedness, and hast said: There is none that seeth me. Thy wisdom, and, thy knowledge, this hath deceived thee. And thou hast said in thy heart: I am, and besides me there is no other.", "bbe": "For you had faith in your evil-doing; you said, No one sees me; by your wisdom and knowledge you have been turned out of the way: and you have said in your heart, I am, and there is no other.", "geneva": "For thou hast trusted in thy wickednesse: thou hast sayd, None seeth me. Thy wisdom and thy knowledge, they haue caused thee to rebel, and thou hast saide in thine heart, I am, and none els.", "wycliffe": "And thou haddist trist in thi malice, and seidist, Noon is that seeth me; this thi wisdom and thi kunnyng disseyuede thee; and thou seidist in thin herte,", "rotherham": "And so thou didst trust in thy wickedness, Thou saidst, no one, seeth me, Thy wisdom and knowledge, the same, seduced thee,—Therefore saidst thou in thy heart, I [am], and there is no one besides.", "darby": "For thou hast confided in thy wickedness: thou hast said, None seeth me. Thy wisdom and thy knowledge, it hath seduced thee; and thou hast said in thy heart, It is I, and there is none but me.", "twenty": "", "jps": "And thou hast been secure in thy wickedness, thou hast said: 'None seeth me'; thy wisdom and thy knowledge, it hath perverted thee; and thou hast said in thy heart. 'I am, and there is none else beside me.'", "acv": "For thou have trusted in thy wickedness. Thou have said, None sees me. Thy wisdom and thy knowledge, it has perverted thee. And thou have said in thy heart, I am, and there is none else besides me.", "anderson": "", "haweis": "", "noyes": "Thou didst trust in thy wickedness, and saidst, \"No one seeth me\"; Thy wisdom and thy knowledge have led thee astray; Thou saidst in thy heart, \"I am, and there is none besides me\";", "webster": "For thou hast trusted in thy wickedness: thou hast said, None seeth me. Thy wisdom and thy knowledge, it hath perverted thee; and thou hast said in thy heart, I [am], and none else besides me.", "vulgate": "et fiduciam habuisti in malitia tua et dixisti non est qui videat me sapientia tua et scientia tua haec decepit te et dixisti in corde tuo ego sum et praeter me non est altera;", "brenton": "for thy trusting in wickedness: for thou saidst, I am, and there is not another: know thou, the understanding of these things and thy harlotry shall be thy shame; for thou saidst in thy heart, I am, and there is not another."}}, {"v": 11, "ref": "47:11", "o": "וּ/בָ֧א עָלַ֣יִ/ךְ רָעָ֗ה לֹ֤א תֵדְעִי֙ שַׁחְרָ֔/הּ וְ/תִפֹּ֤ל עָלַ֨יִ/ךְ֙ הֹוָ֔ה לֹ֥א תוּכְלִ֖י כַּפְּרָ֑/הּ וְ/תָבֹ֨א עָלַ֧יִ/ךְ פִּתְאֹ֛ם שׁוֹאָ֖ה לֹ֥א תֵדָֽעִי", "en": {"kjv": "Therefore shall evil come upon thee; thou shalt not know from whence it riseth: and mischief shall fall upon thee; thou shalt not be able to put it off: and desolation shall come upon thee suddenly, which thou shalt not know.", "web": "Therefore evil will come on you; you won’t know when it dawns: and mischief will fall on you; you will not be able to put it away: and desolation shall come on you suddenly, which you don’t know.", "bsb": "But disaster will come upon you; you will not know how to charm it away. A calamity will befall you that you will be unable to ward off. Devastation will happen to you suddenly and unexpectedly.", "asv": "Therefore shall evil come upon thee; thou shalt not know the dawning thereof: and mischief shall fall upon thee; thou shalt not be able to put it away: and desolation shall come upon thee suddenly, which thou knowest not.", "ylt": "And come in on thee hath evil, Thou knowest not its rising, And fall on thee doth mischief, Thou art not able to pacify it, And come on thee suddenly doth desolation, Thou knowest not.", "dra": "Evil shall come upon thee, and thou shalt not know the rising thereof: and calamity shall fall violently upon thee, which thou canst not keep off: misery shall come upon thee suddenly, which thou shalt not know.", "bbe": "Because of this evil will come on you, which may not be turned away for any price: and trouble will overtake you, from which no money will give salvation: destruction will come on you suddenly, without your knowledge.", "geneva": "Therefore shall euill come vpon thee, and thou shalt not knowe the morning thereof: destruction shall fal vpon thee, which thou shalt not be able to put away: destruction shall come vpon thee suddenly, or thou beware.", "wycliffe": "Y am, and outakun me ther is noon other. Yuel schal come on thee, and thou schalt not knowe the bigynning therof; and wrecchidnesse schal falle on thee, which thou schalt not mowe clense; wretchidnesse which thou knowist not, schal come on thee sudenly.", "rotherham": "Therefore shall come on thee—Mischief, Thou shalt not know how to charm it away Yea there shall fall on thee, Ruin, Thou shalt not be able to appease it,—And there shall come on thee suddenly. Desolation. Thou shalt not know.", "darby": "But evil shall come upon thee — thou shalt not know from whence it riseth; and mischief shall fall upon thee, which thou shalt not be able to ward off; and desolation that thou suspectest not shall come upon thee suddenly.", "twenty": "", "jps": "Yet shall evil came upon thee; thou shalt not know how to charm it away; and calamity shall fall upon thee; thou shalt not be able to put it away; and ruin shall come upon thee suddenly, before thou knowest.", "acv": "Therefore evil shall come upon thee. Thou shall not know the dawning of it. And mischief shall fall upon thee. Thou shall not be able to put it away. And desolation shall come upon thee suddenly, which thou know not.", "anderson": "", "haweis": "", "noyes": "Therefore shall evil come upon thee, of which thou shalt not know the dawn; And mischief shall fall upon thee, which thou shalt not be able to expiate; Suddenly shall desolation come upon thee, when thou thinkest not of it.", "webster": "Therefore shall evil come upon thee; thou shalt not know from whence it riseth: and mischief shall fall upon thee; thou shalt not be able to put it off: and desolation shall come upon thee suddenly, [which] thou shalt not know.", "vulgate": "veniet super te malum et nescies ortum eius et inruet super te calamitas quam non poteris expiare veniet super te repente miseria quam nescies;", "brenton": "And destruction shall come upon thee, and thou shalt not be aware; there shall be a pit, and thou shalt fall into it: and grief shall come upon thee, and thou shalt not be able to be clear; and destruction shall come suddenly upon thee, and thou shalt not know."}}, {"v": 12, "ref": "47:12", "o": "עִמְדִי נָ֤א בַ/חֲבָרַ֨יִ/ךְ֙ וּ/בְ/רֹ֣ב כְּשָׁפַ֔יִ/ךְ בַּ/אֲשֶׁ֥ר יָגַ֖עַתְּ מִ/נְּעוּרָ֑יִ/ךְ אוּלַ֛י תּוּכְלִ֥י הוֹעִ֖יל אוּלַ֥י תַּעֲרֽוֹצִי", "en": {"kjv": "Stand now with thine enchantments, and with the multitude of thy sorceries, wherein thou hast laboured from thy youth; if so be thou shalt be able to profit, if so be thou mayest prevail.", "web": "“Stand now with your enchantments, and with the multitude of your sorceries, in which you have labored from your youth; if so be you shall be able to profit, if so be you may prevail.", "bsb": "So take your stand with your spells and with your many sorceries, with which you have wearied yourself from your youth. Perhaps you will succeed; perhaps you will inspire terror!", "asv": "Stand now with thine enchantments, and with the multitude of thy sorceries, wherein thou hast labored from thy youth; if so be thou shalt be able to profit, if so be thou mayest prevail.", "ylt": "Stand, I pray thee, in thy charms, And in the multitude of thy sorceries, In which thou hast laboured from thy youth, It may be thou art able to profit, It may be thou dost terrify!", "dra": "Stand now with thy enchanters, and with the multitude of thy sorceries, in which thou hast laboured from thy youth, if so be it may profit thee any thing, or if thou mayst become stronger.", "bbe": "Go on now with your secret arts, and all your wonder-working, to which you have given yourself up from your earliest days; it may be that they will be of profit to you, or by them you may put fear into your attackers.", "geneva": "Stand now among thine inchanters, and in the multitude of thy southsaiers (with whome thou hast wearied thy selfe from thy youth) if so be thou maist haue profit, or if so be thou maist haue strength.", "wycliffe": "Stonde thou with thin enchauntours, and with the multitude of thi witchis, in whiche thou trauelidist fro thi yongthe; if in hap thei profiten ony thing to thee, ether if thou maist be maad the strongere.", "rotherham": "Take thy stand, I pray thee, With thy spells. And with the throng of thine incantations wherein thou hast wearied thyself from thy youth,—Peradventure thou mayest be able to profit Peradventure thou mayest strike me with terror.", "darby": "Stand now with thine enchantments and with the multitude of thy sorceries, wherein thou hast laboured from thy youth; if so be thou shalt be able to turn them to profit, if so be thou mayest cause terror.", "twenty": "", "jps": "Stand now with thine enchantments, and with the multitude of thy sorceries, wherein thou hast laboured from thy youth; if so be thou shalt be able to profit, if so be thou mayest prevail.", "acv": "Stand now with thine enchantments, and with the multitude of thy sorceries, in which thou have labored from thy youth, if so be thou shall be able to profit, if so be thou may prevail.", "anderson": "", "haweis": "", "noyes": "Persevere now in thy enchantments; In the multitude of thy sorceries, in which thou hast labored from thy youth; Perhaps thou mayst be profited by them! Perhaps thou mayst make thyself feared!", "webster": "Stand now with thy enchantments, and with the multitude of thy sorceries, in which thou hast labored from thy youth; if thou shalt be able to profit, if thou mayest prevail.", "vulgate": "sta cum incantatoribus tuis et cum multitudine maleficiorum tuorum in quibus laborasti ab adulescentia tua si forte quid prosit tibi aut si possis fieri fortior;", "brenton": "Stand now with thine enchantments, and with the abundance of thy sorcery, which thou hast learned from thy youth; if thou canst be profited."}}, {"v": 13, "ref": "47:13", "o": "נִלְאֵ֖ית בְּ/רֹ֣ב עֲצָתָ֑יִ/ךְ יַעַמְדוּ נָ֨א וְ/יוֹשִׁיעֻ֜/ךְ הברו הֹבְרֵ֣י שָׁמַ֗יִם הַֽ/חֹזִים֙ בַּ/כּ֣וֹכָבִ֔ים מֽוֹדִיעִם֙ לֶ/חֳדָשִׁ֔ים מֵ/אֲשֶׁ֥ר יָבֹ֖אוּ עָלָֽיִ/ךְ", "en": {"kjv": "Thou art wearied in the multitude of thy counsels. Let now the astrologers, the stargazers, the monthly prognosticators, stand up, and save thee from these things that shall come upon thee.", "web": "You are wearied in the multitude of your counsels: let now the astrologers, the stargazers, the monthly prognosticators, stand up, and save you from the things that shall come on you.", "bsb": "You are wearied by your many counselors; let them come forward now and save you— your astrologers who observe the stars, who monthly predict your fate.", "asv": "Thou art wearied in the multitude of thy counsels: let now the astrologers, the star-gazers, the monthly prognosticators, stand up, and save thee from the things that shall come upon thee.", "ylt": "Thou hast been wearied in the multitude of thy counsels, Stand up, I pray thee, and save thee, Let the charmers of the heavens, Those looking on the stars, Those teaching concerning the months, From those things that come on thee!", "dra": "Thou hast failed in the multitude of thy counsels: let now the astrologers stand and save thee, they that gazed at the stars, and counted the months, that from them they might tell the things that shall come to thee.", "bbe": "But your mind is troubled by the number of your guides: let them now come forward for your salvation: the measurers of the heavens, the watchers of the stars, and those who are able to say from month to month what things are coming on you.", "geneva": "Thou art wearied in the multitude of thy counsels: let now the astrologers, the starre gasers, and prognosticatours stand vp, and saue thee from these things, that shall come vpon thee.", "wycliffe": "Thou failidist in the multitude of thi councels; the false dyuynours of heuene stonde, and saue thee, whiche bihelden staris, and noumbriden monethis, that thei schulden telle bi tho thingis to comynge to thee.", "rotherham": "Thou hast worn thyself out with the mass of thy consultations,—Let them take their stand I pray thee that they may save thee—The dividers of the heavens—The gazers at the stars, They who make known by new moons, Somewhat of the things which shall come upon thee.", "darby": "Thou art wearied in the multitude of thy counsels. Let now the interpreters of the heavens, the observers of the stars, who predict according to the new moons what shall come upon thee, stand up, and save thee.", "twenty": "", "jps": "Thou art wearied in the multitude of thy counsels; let now the astrologers, the stargazers, the monthly prognosticators, stand up, and save thee from the things that shall come upon thee.", "acv": "Thou are wearied in the multitude of thy counsels. Let now the astrologers, the star-gazers, the monthly prognosticators, stand up, and save thee from the things that shall come upon thee.", "anderson": "", "haweis": "", "noyes": "Art thou wearied with thy many devices? Let them stand up, then, and save thee, The observers of the heavens, the star-gazers, They that prognosticate at every new moon The things that shall come upon thee!", "webster": "Thou art wearied in the multitude of thy counsels. Let now the astrologers, the star-gazers, the monthly prognosticators, stand up, and save thee from [these things] that shall come upon thee.", "vulgate": "defecisti in multitudine consiliorum tuorum stent et salvent te augures caeli qui contemplabantur sidera et supputabant menses ut ex eis adnuntiarent ventura tibi;", "brenton": "Thou art wearied in thy counsels. Let now the astrologers of the heaven stand and deliver thee, let them that see the stars tell thee what is about to come upon thee."}}, {"v": 14, "ref": "47:14", "o": "הִנֵּ֨ה הָי֤וּ כְ/קַשׁ֙ אֵ֣שׁ שְׂרָפָ֔תַ/ם לֹֽא יַצִּ֥ילוּ אֶת נַפְשָׁ֖/ם מִ/יַּ֣ד לֶֽהָבָ֑ה אֵין גַּחֶ֣לֶת לַ/חְמָ֔ם א֖וּר לָ/שֶׁ֥בֶת נֶגְדּֽ/וֹ", "en": {"kjv": "Behold, they shall be as stubble; the fire shall burn them; they shall not deliver themselves from the power of the flame: there shall not be a coal to warm at, nor fire to sit before it.", "web": "Behold, they shall be as stubble; the fire shall burn them; they shall not deliver themselves from the power of the flame: it shall not be a coal to warm at, nor a fire to sit before.", "bsb": "Surely they are like stubble; the fire will burn them up. They cannot deliver themselves from the power of the flame. There will be no coals to warm them or fire to sit beside.", "asv": "Behold, they shall be as stubble; the fire shall burn them; they shall not deliver themselves from the power of the flame: it shall not be a coal to warm at, nor a fire to sit before.", "ylt": "Lo, they have been as stubble! Fire hath burned them, They deliver not themselves from the power of the flame, There is not a coal to warm them, a light to sit before it.", "dra": "Behold they are as stubble, fire hath burnt them, they shall not deliver themselves from the power of the flames: there are no coals wherewith they may be warmed, nor fire, that they may sit thereat.", "bbe": "Truly, they have become like dry stems, they have been burned in the fire; they are not able to keep themselves safe from the power of the flame: it is not a coal for warming them, or a fire by which a man may be seated.", "geneva": "Beholde, they shall be as stubble: the fire shall burne them: they shall not deliuer their owne liues from the power of the flame: there shalbe no coles to warme at, nor light to sit by.", "wycliffe": "Lo! thei ben maad as stobil, the fier hath brent hem; thei schulen not delyuere her lijf fro the power of flawme; colis ben not, bi whiche thei schulen be warmed, nether fier, that thei sitte at it.", "rotherham": "Lo! they have become as straw—a fire, hath burned them up, They shall not deliver their own soul from the grasp of the flame,—There is, no live coal to warm them, nor blaze to sit before.", "darby": "Behold, they shall be as stubble, the fire shall burn them; they shall not deliver themselves from the power of the flame: there shall not be a coal to warm at, [nor] fire to sit before it.", "twenty": "", "jps": "Behold, they shall be as stubble; the fire shall burn them; they shall not deliver themselves from the power of the flame; it shall not be a coal to warm at, nor a fire to sit before.", "acv": "Behold, they shall be as stubble. The fire shall burn them. They shall not deliver themselves from the power of the flame. It shall not be a coal to warm at, nor a fire to sit before.", "anderson": "", "haweis": "", "noyes": "Behold, they shall be like stubble; the fire shall burn them up; They shall not deliver themselves from the power of the flame; Not a coal shall be left of them to warm one, Nor a spark of fire to sit by.", "webster": "Behold, they shall be as stubble; the fire shall burn them; they shall not deliver themselves from the power of the flame: [there shall] not [be] a coal to warm at, [nor] fire to sit before it.", "vulgate": "ecce facti sunt quasi stipula ignis conbusit eos non liberabunt animam suam de manu flammae non sunt prunae quibus calefiant nec focus ut sedeant ad eum;", "brenton": "Behold, they all shall be burnt up as sticks in the fire; neither shall they at all deliver their life from the flame. Because thou hast coals of fire, sit thou upon them;"}}, {"v": 15, "ref": "47:15", "o": "כֵּ֥ן הָיוּ לָ֖/ךְ אֲשֶׁ֣ר יָגָ֑עַתְּ סֹחֲרַ֣יִ/ךְ מִ/נְּעוּרַ֗יִ/ךְ אִ֤ישׁ לְ/עֶבְר/וֹ֙ תָּע֔וּ אֵ֖ין מוֹשִׁיעֵֽ/ךְ", "en": {"kjv": "Thus shall they be unto thee with whom thou hast laboured, even thy merchants, from thy youth: they shall wander every one to his quarter; none shall save thee.", "web": "Thus shall the things be to you in which you have labored: those who have trafficked with you from your youth shall wander everyone to his quarter; there shall be no one to save you.", "bsb": "This is what they are to you— those with whom you have labored and traded from youth— each one strays in his own direction; not one of them can save you.", "asv": "Thus shall the things be unto thee wherein thou hast labored: they that have trafficked with thee from thy youth shall wander every one to his quarter; there shall be none to save thee.", "ylt": "So have they been to thee with whom thou hast laboured, Thy merchants from thy youth, Each to his passage they have wandered, Thy saviour is not!", "dra": "Such are all the things become to thee, in which thou hast laboured: thy merchants from thy youth, every one hath erred in his own way, there is none that can save thee.", "bbe": "Small profit have you had from those who, from your earliest days, got great profit out of you; they have gone in flight, every one straight before him, and you have no saviour.", "geneva": "Thus shall they serue thee, with whom thou hast wearied thee, euen thy marchants from thy youth: euery one shall wander to his owne quarter: none shall saue thee.", "wycliffe": "So tho thingis ben maad to thee in whiche euere thou trauelidist; thi marchauntis fro thi yongthe erriden, ech man in his weie; noon is, that schal saue thee.", "rotherham": "Such, have they become to thee, with whom thou hast wearied thyself,—Thy merchants—from thy youth, will every man stagger straight onwards—There is none to save thee.", "darby": "Thus shall they be unto thee with whom thou hast laboured, they that trafficked with thee from thy youth: they shall wander every one to his own quarter; there is none to save thee.", "twenty": "", "jps": "Thus shall they be unto thee with whom thou hast laboured; they that have trafficked with thee from thy youth shall wander every one to his quarter; there shall be none to save thee.", "acv": "Thus shall be the things to thee, in which thou have labored. Those who have trafficked with thee from thy youth shall wander each one to his quarter. There shall be none to save thee.", "anderson": "", "haweis": "", "noyes": "Thus shall it be with them with whom thou hast labored; Thus with them with whom thou hast trafficked from thy youth; They shall go every one his own way; None shall help thee.", "webster": "Thus shall they be to thee with whom thou hast labored, [even] thy merchants, from thy youth: they shall wander every one to his quarter; none shall save thee.", "vulgate": "sic facta sunt tibi in quibuscumque laboraveras negotiatores tui ab adulescentia tua unusquisque in via sua erraverunt non est qui salvet te;", "brenton": "these shall be thy help. Thou hast wearied thyself with traffic from thy youth: every man has wandered to his own home, but thou shalt have no deliverance."}}]}, {"c": 48, "verses": [{"v": 1, "ref": "48:1", "o": "שִׁמְעוּ זֹ֣את בֵּֽית יַעֲקֹ֗ב הַ/נִּקְרָאִים֙ בְּ/שֵׁ֣ם יִשְׂרָאֵ֔ל וּ/מִ/מֵּ֥י יְהוּדָ֖ה יָצָ֑אוּ הַֽ/נִּשְׁבָּעִ֣ים בְּ/שֵׁ֣ם יְהוָ֗ה וּ/בֵ/אלֹהֵ֤י יִשְׂרָאֵל֙ יַזְכִּ֔ירוּ לֹ֥א בֶ/אֱמֶ֖ת וְ/לֹ֥א בִ/צְדָקָֽה", "en": {"kjv": "Hear ye this, O house of Jacob, which are called by the name of Israel, and are come forth out of the waters of Judah, which swear by the name of the Lord, and make mention of the God of Israel, but not in truth, nor in righteousness.", "web": "“Hear this, house of Jacob, you who are called by the name of Israel, and have come out of the waters of Judah; who swear by Yahweh’s name, and make mention of the God of Israel, but not in truth, nor in righteousness", "bsb": "“Listen to this, O house of Jacob, you who are called by the name of Israel, who have descended from the line of Judah, who swear by the name of the LORD, who invoke the God of Israel— but not in truth or righteousness—", "asv": "Hear ye this, O house of Jacob, who are called by the name of Israel, and are come forth out of the waters of Judah; who swear by the name of Jehovah, and make mention of the God of Israel, but not in truth, nor in righteousness", "ylt": "Hear ye this, O house of Jacob, Who are called by the name of Israel, And from the waters of Judah came out, Who are swearing by the name of Jehovah, And of the God of Israel make mention, Not in truth nor in righteousness.", "dra": "Hear ye these things, O house of Jacob, you that are called by the name of Israel, and are come forth out of the waters of Juda, you who swear by the name of the Lord, and make mention of the God of Israel, but not in truth, nor in justice.", "bbe": "Give ear to this, O family of Jacob, you who are named by the name of Israel, and have come out of the body of Judah; who take oaths by the name of the Lord, and make use of the name of the God of Israel, but not truly and not in good faith.", "geneva": "Hear yee this, O house of Iaakob, which are called by the name of Israel, and are come out of the waters of Iudah: which sweare by the Name of the Lord, and make mention of the God of Israel, but not in truth, nor in righteousnesse.", "wycliffe": "The hows of Jacob, that ben clepid bi the name of Israel, and yeden out of the watris of Juda, here these thingis, whiche sweren in the name of the Lord, and han mynde on God of Israel, not in treuthe, nether in riytfulnesse.", "rotherham": "Hear ye this—O house of Jacob, Ye who call yourselves by the name of Israel, Yea from the waters of Judah, came they forth,—Who swear by the name of Yahweh, And, by the God of Israel, call to remembrance—Not in truth, nor in righteousness;", "darby": "Hear ye this, house of Jacob, who are called by the name of Israel, and are come forth out of the waters of Judah, who swear by the name of Jehovah, and make mention of theGod of Israel, not in truth, nor in righteousness.", "twenty": "", "jps": "Hear ye this, O house of Jacob, who are called by the name of Israel, and are come forth out of the fountain of Judah; who swear by the name of HaShem, and make mention of the G-d of Israel, but not in truth, nor in righteousness.", "acv": "Hear ye this, O house of Jacob, who are called by the name of Israel, and have come forth out of the waters of Judah, who swear by the name of Jehovah, and make mention of the God of Israel, but not in truth, nor in righteousness", "anderson": "", "haweis": "", "noyes": "Hear this, O house of Jacob! Ye that are called by the name of Israel; Ye that have come forth from the fountain of Judah; Ye that swear by the name of Jehovah, And praise the God of Israel, But not in truth and sincerity!", "webster": "Hear ye this, O house of Jacob, who are called by the name of Israel, and have come forth out of the waters of Judah, who swear by the name of the LORD, and make mention of the God of Israel, [but] not in truth, nor in righteousness.", "vulgate": "audite hoc domus Iacob qui vocamini nomine Israhel et de aquis Iuda existis qui iuratis in nomine Domini et Dei Israhel recordamini non in veritate neque in iustitia;", "brenton": "Hear these words, ye house of Jacob, who are called by the name of Israel, and have come forth out of Juda, who swear by the name of the Lord God of Israel, making mention of it, but not with truth, nor with righteousness;"}}, {"v": 2, "ref": "48:2", "o": "כִּֽי מֵ/עִ֤יר הַ/קֹּ֨דֶשׁ֙ נִקְרָ֔אוּ וְ/עַל אֱלֹהֵ֥י יִשְׂרָאֵ֖ל נִסְמָ֑כוּ יְהוָ֥ה צְבָא֖וֹת שְׁמֽ/וֹ", "en": {"kjv": "For they call themselves of the holy city, and stay themselves upon the God of Israel; The Lord of hosts is his name.", "web": "(for they call themselves of the holy city, and stay themselves on the God of Israel; Yahweh of Armies is his name):", "bsb": "who indeed call yourselves after the holy city and lean on the God of Israel; the LORD of Hosts is His name.", "asv": "(for they call themselves of the holy city, and stay themselves upon the God of Israel; Jehovah of hosts is his name):", "ylt": "For from the Holy City they have been called, And on the God of Israel been supported, Jehovah of Hosts is His name.", "dra": "For they are called of the holy city, and are established upon the God of Israel: the Lord of hosts is his name.", "bbe": "For they say that they are of the holy town, and put their faith in the God of Israel: the Lord of armies is his name.", "geneva": "For they are called of the holy citie, and staie themselues vpon the God of Israel, whose Name is the Lord of hostes.", "wycliffe": "For thei ben clepid of the hooli citee, and ben stablischid on the God of Israel, the Lord of oostis is his name.", "rotherham": "For of the holy city, do they call themselves, And on the God of Israel, do they stay themselves,—Yahweh of hosts, is his name.", "darby": "For they are named after the holy city, and stay themselves upon theGod of Israel: Jehovah of hosts is his name.", "twenty": "", "jps": "For they call themselves of the holy city, and stay themselves upon the G-d of Israel, HaShem of hosts is His name.", "acv": "(for they call themselves of the holy city, and steady themselves upon the God of Israel, Jehovah of hosts is his name):", "anderson": "", "haweis": "", "noyes": "For they call themselves of the holy city, And stay themselves on the God of Israel, Whose name is Jehovah of hosts:—", "webster": "For they call themselves of the holy city, and stay themselves upon the God of Israel; The LORD of hosts [is] his name.", "vulgate": "de civitate enim sancta vocati sunt et super Deum Israhel constabiliti sunt Dominus exercituum nomen eius;", "brenton": "maintaining also the name of the holy city, and staying themselves on the God of Israel: the Lord of hosts is his name. The former things I have already declared;"}}, {"v": 3, "ref": "48:3", "o": "הָ/רִֽאשֹׁנוֹת֙ מֵ/אָ֣ז הִגַּ֔דְתִּי וּ/מִ/פִּ֥/י יָצְא֖וּ וְ/אַשְׁמִיעֵ֑/ם פִּתְאֹ֥ם עָשִׂ֖יתִי וַ/תָּבֹֽאנָה", "en": {"kjv": "I have declared the former things from the beginning; and they went forth out of my mouth, and I shewed them; I did them suddenly, and they came to pass.", "web": "I have declared the former things from of old; yes, they went out of my mouth, and I showed them: suddenly I did them, and they happened.", "bsb": "I foretold the former things long ago; they came out of My mouth and I proclaimed them. Suddenly I acted, and they came to pass.", "asv": "I have declared the former things from of old; yea, they went forth out of my mouth, and I showed them: suddenly I did them, and they came to pass.", "ylt": "The former things from that time I declared, And from my mouth they have gone forth, And I proclaim them, Suddenly I have done, and it cometh.", "dra": "The former things of old, I have declared, and they went forth out of my mouth, and I have made them to be heard: I did them suddenly and they came to pass.", "bbe": "I gave word in the past of the things which came about; they came from my mouth, and I made them clear: suddenly I did them, and they came about.", "geneva": "I haue declared ye former things of old, and they went out of my mouth, and I shewed them: I did them suddenly, and they came to passe.", "wycliffe": "Fro that tyme Y telde the former thingis, and tho yeden out of my mouth; and Y made tho knowun; sudenli Y wrouyte, and tho thingis camen.", "rotherham": "Things in advance, of old, I declared, Yea out of mine own mouth, came they forth, that I might let them be known,—Suddenly, I wrought and they came to pass.", "darby": "I have declared the former things long ago; and they went forth out of my mouth, and I caused them to be heard: I wrought suddenly, and they came to pass.", "twenty": "", "jps": "I have declared the former things from of old; yea, they went forth out of My mouth, and I announced them; suddenly I did them, and they came to pass.", "acv": "I have declared the former things from of old. Yea, they went forth out of my mouth, and I showed them. Suddenly I did them, and they came to pass.", "anderson": "", "haweis": "", "noyes": "What hath happened I declared to you long ago; From my mouth it proceeded, and I made it known; On a sudden I effected it, and it came to pass.", "webster": "I have declared the former things from the beginning; and they went forth from my mouth, and I showed them; I did [them] suddenly, and they came to pass.", "vulgate": "priora ex tunc adnuntiavi et ex ore meo exierunt et audita feci ea repente operatus sum et venerunt;", "brenton": "and they that have proceeded out of my mouth, and it became well known; I wrought suddenly, and the events came to pass."}}, {"v": 4, "ref": "48:4", "o": "מִ/דַּעְתִּ֕/י כִּ֥י קָשֶׁ֖ה אָ֑תָּה וְ/גִ֤יד בַּרְזֶל֙ עָרְפֶּ֔/ךָ וּ/מִצְחֲ/ךָ֖ נְחוּשָֽׁה", "en": {"kjv": "Because I knew that thou art obstinate, and thy neck is an iron sinew, and thy brow brass;", "web": "Because I knew that you are obstinate, and your neck is an iron sinew, and your brow brass;", "bsb": "For I knew that you are stubborn; your neck is iron and your forehead is bronze.", "asv": "Because I knew that thou art obstinate, and thy neck is an iron sinew, and thy brow brass;", "ylt": "From my knowing that thou art obstinate, And a sinew of iron thy neck, And thy forehead brass,", "dra": "For I knew that thou art stubborn, and thy neck is as an iron sinew, and thy forehead as brass.", "bbe": "Because I saw that your heart was hard, and that your neck was an iron cord, and your brow brass;", "geneva": "Because I knewe, that thou art obstinate, and thy necke is an yron sinew, and thy brow brasse,", "wycliffe": "For Y wiste that thou art hard, and thi nol is a senewe of irun, and thi forhed is of bras.", "rotherham": "Because I knew that—Obstinate, thou wast,—And, a sinew of iron, was thy neck, And thy brow, brazen,", "darby": "Because I knew that thou art obstinate, and thy neck is an iron sinew, and thy brow brass,", "twenty": "", "jps": "Because I knew that thou art obstinate, and thy neck is an iron sinew, and thy brow brass;", "acv": "Because I knew that thou are obstinate, and thy neck is an iron sinew, and thy brow brass,", "anderson": "", "haweis": "", "noyes": "Because I knew that thou art obstinate, And that thy neck is a bar of iron, And that thy brow is brass,", "webster": "Because I knew that thou [art] obstinate, and thy neck [is] an iron sinew, and thy brow brass;", "vulgate": "scivi enim quia durus es tu et nervus ferreus cervix tua et frons tua aerea;", "brenton": "I know that thou art stubborn, and thy neck is an iron sinew, and thy forehead brazen."}}, {"v": 5, "ref": "48:5", "o": "וָ/אַגִּ֤יד לְ/ךָ֙ מֵ/אָ֔ז בְּ/טֶ֥רֶם תָּב֖וֹא הִשְׁמַעְתִּ֑י/ךָ פֶּן תֹּאמַר֙ עָצְבִּ֣/י עָשָׂ֔/ם וּ/פִסְלִ֥/י וְ/נִסְכִּ֖/י צִוָּֽ/ם", "en": {"kjv": "I have even from the beginning declared it to thee; before it came to pass I shewed it thee: lest thou shouldest say, Mine idol hath done them, and my graven image, and my molten image, hath commanded them.", "web": "therefore I have declared it to you from of old; before it came to pass I showed it to you; lest you should say, ‘My idol has done them, and my engraved image, and my molten image, has commanded them.’", "bsb": "Therefore I declared it to you long ago; I announced it before it came to pass, so that you could not claim, ‘My idol has done this; my carved image and molten god has ordained it.’", "asv": "therefore I have declared it to thee from of old; before it came to pass I showed it thee; lest thou shouldest say, Mine idol hath done them, and my graven image, and my molten image, hath commanded them.", "ylt": "And I declare to thee from that time, Before it cometh I have caused thee to hear, Lest thou say, `Mine idol hath done them, And my graven image, And my molten image did command them.", "dra": "I foretold thee of old, before they came to pass I told thee, lest thou shouldst say: My idols have done these things, and my graven and molten things have commanded them.", "bbe": "For this reason I made it clear to you in the past, before it came I gave you word of it: for fear that you might say, My god did these things, and my pictured and metal images made them come about.", "geneva": "Therefore I haue declared it to thee of old: before it came to passe, I shewed it thee, lest thou shouldest say, Mine idole hath done them, and my carued image, and my molten image hath commanded them.", "wycliffe": "Y biforseide to thee fro that tyme, bifore that tho thingis camen, Y schewide to thee, lest perauenture thou woldist seie, Myn idols diden these thingis, and my grauun ymagis and my yotun", "rotherham": "therefore told I thee—in time past, Ere yet it came, I let thee hear,—Lest thou shouldest say Mine idol wrought them, Yea, my carved image and my molten image, commanded them!", "darby": "so I have long ago declared [them] to thee; before they came to pass I caused thee to hear [them]; lest thou shouldest say, Mine idol hath done them, and my graven image, or my molten image hath commanded them.", "twenty": "", "jps": "Therefore I have declared it to thee from of old; before it came to pass I announced it to thee; lest thou shouldest say: 'Mine idol hath done them, and my graven image, and my molten image, hath commanded them.'", "acv": "therefore I have declared it to thee from of old. Before it came to pass I showed it to thee, lest thou should say, My idol has done them. And my graven image, and my molten image, has commanded them.", "anderson": "", "haweis": "", "noyes": "I declared it to thee long ago; Before it came to pass, I made it known to thee; Lest thou shouldst say, My idol effected it, And my graven image, and my molten image ordained it.", "webster": "I have even from the beginning declared [it] to thee; before it came to pass I showed [it] thee: lest thou shouldst say, My idol hath done them, and my graven image, and my molten image, hath commanded them.", "vulgate": "praedixi tibi ex tunc antequam venirent indicavi tibi ne forte diceres idola mea fecerunt haec et sculptilia mea et conflatilia mandaverunt ista;", "brenton": "And I told thee of old what should be before it came upon thee; I made it known to thee, lest thou shouldest say, My idols have done it for me; and shouldest say, My graven and molten images have commanded me."}}, {"v": 6, "ref": "48:6", "o": "שָׁמַ֤עְתָּֽ חֲזֵה֙ כֻּלָּ֔/הּ וְ/אַתֶּ֖ם הֲ/ל֣וֹא תַגִּ֑ידוּ הִשְׁמַעְתִּ֤י/ךָ חֲדָשׁוֹת֙ מֵ/עַ֔תָּה וּ/נְצֻר֖וֹת וְ/לֹ֥א יְדַעְתָּֽ/ם", "en": {"kjv": "Thou hast heard, see all this; and will not ye declare it? I have shewed thee new things from this time, even hidden things, and thou didst not know them.", "web": "You have heard it; see all this; and you, will you not declare it? “I have shown you new things from this time, even hidden things, which you have not known.", "bsb": "You have heard these things; look at them all. Will you not acknowledge them? From now on I will tell you of new things, hidden things unknown to you.", "asv": "Thou hast heard it; behold all this; and ye, will ye not declare it? I have showed thee new things from this time, even hidden things, which thou hast not known.", "ylt": "Thou hast heard, see the whole of it, And ye, do ye not declare? I have caused thee to hear new things from this time, And things reserved that ye knew not.", "dra": "See now all the things which thou hast heard: but have you declared them? I have shewn thee new things from that time, and things are kept which thou knowest not:", "bbe": "All this has come to your ears and you have seen it; will you not give witness to it? I am now making clear new things, even secret things, of which you had no knowledge.", "geneva": "Thou hast heard, behold all this, and wil not yee declare it? I haue shewed thee newe things, euen now, and hid things, which thou knewest not.", "wycliffe": "ymagis senten these thingis whiche thou herdist. Se thou alle thingis, but ye telden not. Y made herd newe thyngis to thee fro that tyme, and thingis ben kept whiche thou knowist not;", "rotherham": "Thou hast heard—see it whole, And will, ye, not tell? I have let thee hear new things—from the present time, Even secrets which ye knew not.", "darby": "Thou heardest, see all this; — and ye, will not ye declare [it]? I have caused thee to hear new things from this time, and things hidden, and that thou knewest not:", "twenty": "", "jps": "Thou hast heard, see, all this; and ye, will ye not declare it? I have announced unto thee new things from this time, even hidden things, which thou hast not known.", "acv": "Thou have heard it, behold all this, and ye, will ye not declare it? I have shown thee new things from this time, even hidden things, which thou have not known.", "anderson": "", "haweis": "", "noyes": "Thou hast heard it; now see it all! And will ye not confess it? From this time I make you hear a new thing, Even a hidden thing, which thou hast not known.", "webster": "Thou hast heard, see all this; and will not ye declare [it]? I have showed ye new things from this time, even hidden things, and thou didst not know them.", "vulgate": "quae audisti vide omnia vos autem non adnuntiastis audita feci tibi nova ex nunc et conservata quae nescis;", "brenton": "Ye have heard all this, but ye have not known: yet I have made known to thee the new things from henceforth, which are coming to pass, and thou saidst not,"}}, {"v": 7, "ref": "48:7", "o": "עַתָּ֤ה נִבְרְאוּ֙ וְ/לֹ֣א מֵ/אָ֔ז וְ/לִ/פְנֵי י֖וֹם וְ/לֹ֣א שְׁמַעְתָּ֑/ם פֶּן תֹּאמַ֖ר הִנֵּ֥ה יְדַעְתִּֽי/ן", "en": {"kjv": "They are created now, and not from the beginning; even before the day when thou heardest them not; lest thou shouldest say, Behold, I knew them.", "web": "They are created now, and not from of old; and before this day you didn’t hear them; lest you should say, ‘Behold, I knew them.’", "bsb": "They are created now, and not long ago; you have not heard of them before today. So you cannot claim, ‘I already knew them!’", "asv": "They are created now, and not from of old; and before this day thou heardest them not; lest thou shouldest say, Behold, I knew them.", "ylt": "Now they have been produced and not from that time, Yea, before the day, and thou hast not heard them, Lest thou say, `Lo, I have known them.'", "dra": "They are created now, and not of old: and before the day, when thou heardest them not, lest thou shouldst say: Behold I knew them.", "bbe": "They have only now been effected, and not in the past: and before this day they had not come to your ears; for fear that you might say, I had knowledge of them.", "geneva": "They are created now, and not of olde, and euen before this thou heardest them not, lest thou shouldest say, Beholde, I knewe them.", "wycliffe": "now tho ben maad of nouyt, and not fro that tyme, and bifor the dai, and thou herdist not tho thingis; lest perauenture thou seie, Lo! Y knew tho thingis.", "rotherham": "Now, are they created, and not in time past, And, before to-day, thou hadst not heard of them,—Lest thou shouldest say, Lo! I knew them!", "darby": "they are created now, and not long ago; and before this day thou hast not heard them, lest thou shouldest say, Behold, I knew them.", "twenty": "", "jps": "They are created now, and not from of old, and before this day thou heardest them not; lest thou shouldest say: 'Behold, I knew them.'", "acv": "They are created now, and not from of old. And thou have not heard them before this day, lest thou should say, Behold, I knew them.", "anderson": "", "haweis": "", "noyes": "It is produced now, and not long ago; Before this day thou hast not heard of it, Lest thou shouldst say, Behold, I knew it.", "webster": "They are created now, and not from the beginning; even before the day when thou heardst them not; lest thou shouldst say, Behold, I knew them.", "vulgate": "nunc creata sunt et non ex tunc et ante diem et non audisti ea ne forte dicas ecce cognovi ea;", "brenton": "Now they come to pass, and not formerly: and thou heardest not of them in former days: say not thou, Yea, I know them."}}, {"v": 8, "ref": "48:8", "o": "גַּ֣ם לֹֽא שָׁמַ֗עְתָּ גַּ֚ם לֹ֣א יָדַ֔עְתָּ גַּ֕ם מֵ/אָ֖ז לֹא פִתְּחָ֣ה אָזְנֶ֑/ךָ כִּ֤י יָדַ֨עְתִּי֙ בָּג֣וֹד תִּבְגּ֔וֹד וּ/פֹשֵׁ֥עַ מִ/בֶּ֖טֶן קֹ֥רָא לָֽ/ךְ", "en": {"kjv": "Yea, thou heardest not; yea, thou knewest not; yea, from that time that thine ear was not opened: for I knew that thou wouldest deal very treacherously, and wast called a transgressor from the womb.", "web": "Yes, you didn’t hear; yes, you didn’t know; yes, from of old your ear was not opened: for I knew that you dealt very treacherously, and was called a transgressor from the womb.", "bsb": "You have never heard; you have never understood; for a long time your ears have not been open. For I knew how deceitful you are; you have been called a rebel from birth.", "asv": "Yea, thou heardest not; yea, thou knewest not; yea, from of old thine ear was not opened: for I knew that thou didst deal very treacherously, and wast called a transgressor from the womb.", "ylt": "Yea, thou hast not heard, Yea, thou hast not known, Yea, from that time not opened hath thine ear, For I have known thou dealest treacherously, And `Transgressor from the belly,' One is crying to thee.", "dra": "Thou hast neither heard, nor known, neither was thy ear opened of old. For I know that transgressing thou wilt transgress, and I have called thee a transgressor from the womb.", "bbe": "Truly you had no word of them, no knowledge of them; no news of them in the past had come to your ears; because I saw how false was your behaviour, and that your heart was turned against me from your earliest days.", "geneva": "Yet thou heardest them not, neither diddest know them, neither yet was thine eare opened of olde: for I knewe that thou wouldest grieuously transgresse: therefore haue I called thee a transgressour from the wombe.", "wycliffe": "Nether thou herdist, nether thou knewist, nether thin eere was openyd fro that tyme; for Y woot, that thou trespassynge schal trespasse, and Y clepide thee a trespassour fro the wombe.", "rotherham": "Nay! thou hadst not heard, Nay! thou hadst not known, Nay! in time past, thine ear, was not opened,—For I knew that thou, wouldst be treacherous, Yea a transgressor from birth, hast thou been called.", "darby": "Yea, thou heardest not, yea, thou knewest not, yea, from of old thine ear was not opened; for I knew that thou wouldest ever deal treacherously, and thou wast called a transgressor from the womb.", "twenty": "", "jps": "Yea, thou heardest not; yea, thou knewest not; yea, from of old thine ear was not opened; for I knew that thou wouldest deal very treacherously, and wast called a transgressor from the womb.", "acv": "Yea, thou heard not. Yea, thou knew not. Yea, from of old thine ear was not opened. For I knew that thou dealt very treacherously, and were called a transgressor from the womb.", "anderson": "", "haweis": "", "noyes": "Yea, thou heardest it not; yea, thou knewest it not; Yea, it was not disclosed to thee long ago; For I knew that thou wast wholly faithless, And wast called rebellious from thy birth.", "webster": "Yes, thou heardst not; yes, thou knewest not; yes, from that time [that] thy ear was not opened: for I knew that thou wouldst deal very treacherously, and wast called a transgressor from the womb.", "vulgate": "neque audisti neque cognovisti neque ex tunc aperta est auris tua scio enim quia praevaricans praevaricabis et transgressorem ex ventre vocavi te;", "brenton": "Thou hast neither known, nor understood, neither from the beginning have I opened thine ears: for I knew that thou wouldest surely deal treacherously, and wouldest be called a transgressor even from the womb."}}, {"v": 9, "ref": "48:9", "o": "לְמַ֤עַן שְׁמִ/י֙ אַאֲרִ֣יךְ אַפִּ֔/י וּ/תְהִלָּתִ֖/י אֶחֱטָם לָ֑/ךְ לְ/בִלְתִּ֖י הַכְרִיתֶֽ/ךָ", "en": {"kjv": "For my name’s sake will I defer mine anger, and for my praise will I refrain for thee, that I cut thee not off.", "web": "For my name’s sake will I defer my anger, and for my praise will I refrain for you, that I not cut you off.", "bsb": "For the sake of My name I will delay My wrath; for the sake of My praise I will restrain it, so that you will not be cut off.", "asv": "For my name’s sake will I defer mine anger, and for my praise will I refrain for thee, that I cut thee not off.", "ylt": "For My name's sake I defer Mine anger, And My praise I restrain for thee, So as not to cut thee off.", "dra": "For my name's sake I will remove my wrath far off: and for my praise I will bridle thee, lest thou shouldst perish.", "bbe": "Because of my name I will put away my wrath, and for my praise I will keep myself from cutting you off.", "geneva": "For my Names sake will I defer my wrath, and for my praise will I refraine it from thee, that I cut thee not off.", "wycliffe": "For my name Y schal make fer my strong veniaunce, and with my preysyng Y schal refreyne thee, lest thou perische.", "rotherham": "For the sake of mine own Name, will I defer mine anger, And for my praise, will I restrain myself towards thee,—So as not to cut thee off.", "darby": "For my name's sake I will defer mine anger, and [for] my praise will I refrain as to thee, that I cut thee not off.", "twenty": "", "jps": "For My name's sake will I defer Mine anger, and for My praise will I refrain for thee, that I cut thee not off.", "acv": "For my name's sake I will defer my anger, and for my praise I will refrain for thee, that I not cut thee off.", "anderson": "", "haweis": "", "noyes": "For the sake of my name I will defer my anger, And for the sake of my praise I will restrain it from thee, That I may not utterly cut thee off.", "webster": "For my name's sake will I defer my anger, and for my praise will I refrain for thee, that I cut thee not off.", "vulgate": "propter nomen meum longe faciam furorem meum et laude mea infrenabo te ne intereas;", "brenton": "For mine own sake will I shew thee my wrath, and will bring before thee my glorious acts, that I may not utterly destroy thee."}}, {"v": 10, "ref": "48:10", "o": "הִנֵּ֥ה צְרַפְתִּ֖י/ךָ וְ/לֹ֣א בְ/כָ֑סֶף בְּחַרְתִּ֖י/ךָ בְּ/כ֥וּר עֹֽנִי", "en": {"kjv": "Behold, I have refined thee, but not with silver; I have chosen thee in the furnace of affliction.", "web": "Behold, I have refined you, but not as silver; I have chosen you in the furnace of affliction.", "bsb": "See, I have refined you, but not as silver; I have tested you in the furnace of affliction.", "asv": "Behold, I have refined thee, but not as silver; I have chosen thee in the furnace of affliction.", "ylt": "Lo, I have refined thee, and not with silver, I have chosen thee in a furnace of affliction.", "dra": "Behold I have refined thee, but not as silver, I have chosen thee in the furnace of poverty.", "bbe": "See, I have been testing you for myself like silver; I have put you through the fire of trouble.", "geneva": "Behold, I haue fined thee, but not as siluer: I haue chosen thee in the fornace of affliction.", "wycliffe": "Lo! Y haue sode thee, but not as siluer; Y chees thee in the chymeney of pouert.", "rotherham": "Lo! I have refined thee, but not as silver,—I have tested thee, in a smelting-pot of affliction.", "darby": "Behold, I have refined thee, but not as silver; I have chosen thee in the furnace of affliction.", "twenty": "", "jps": "Behold, I have refined thee, but not as silver; I have tried thee in the furnace of affliction.", "acv": "Behold, I have refined thee, but not as silver. I have chosen thee in the furnace of affliction.", "anderson": "", "haweis": "", "noyes": "Behold, I have melted thee, and found no silver; I have tried thee in the furnace of affliction.", "webster": "Behold, I have refined thee, but not with silver; I have chosen thee in the furnace of affliction.", "vulgate": "ecce excoxi te sed non quasi argentum elegi te in camino paupertatis;", "brenton": "Behold, I have sold thee, but not for silver; but I have rescued thee from the furnace of affliction."}}, {"v": 11, "ref": "48:11", "o": "לְמַעֲנִ֧/י לְמַעֲנִ֛/י אֶעֱשֶׂ֖ה כִּ֣י אֵ֣יךְ יֵחָ֑ל וּ/כְבוֹדִ֖/י לְ/אַחֵ֥ר לֹֽא אֶתֵּֽן", "en": {"kjv": "For mine own sake, even for mine own sake, will I do it: for how should my name be polluted? and I will not give my glory unto another.", "web": "For my own sake, for my own sake, will I do it; for how should my name be profaned? I will not give my glory to another.", "bsb": "For My own sake, My very own sake, I will act; for how can I let Myself be defamed? I will not yield My glory to another.", "asv": "For mine own sake, for mine own sake, will I do it; for how should my name be profaned? and my glory will I not give to another.", "ylt": "For My sake, for Mine own sake, I do it , For how is it polluted? And Mine honour to another I give not.", "dra": "For my own sake, for my own sake will I do it, that I may not be blasphemed: and I will not give my glory to another.", "bbe": "For myself, even because of my name, I will do it; for I will not let my name be shamed; and my glory I will not give to another.", "geneva": "For mine owne sake, for mine owne sake wil I doe it: for how should my Name be polluted? surely I wil not giue my glory vnto another.", "wycliffe": "Y schal do for me, that Y be not blasfemyd, and Y schal not yyue my glorie to another.", "rotherham": "For mine own sake—for mine own sake, will I effectually work For how should it be profaned? And, my glory—to another, will I not give.", "darby": "For mine own sake, for mine own sake, will I do [it]; for how should [my name] be profaned? and I will not give my glory unto another.", "twenty": "", "jps": "For Mine own sake, for Mine own sake, will I do it; for how should it be profaned? And My glory will I not give to another.", "acv": "For my own sake, for my own sake, I will do it. For how should my name be profaned? And I will not give my glory to another.", "anderson": "", "haweis": "", "noyes": "For mine own sake will I do it; For how would my name be blasphemed? And my glory will I not give to another.", "webster": "For my own sake, [even] for my own sake, will I do [it]: for how should [my name] be profaned? and I will not give my glory to another.", "vulgate": "propter me propter me faciam ut non blasphemer et gloriam meam alteri non dabo;", "brenton": "For mine own sake I will do this for thee, because my name is profaned; and I will not give my glory to another."}}, {"v": 12, "ref": "48:12", "o": "שְׁמַ֤ע אֵלַ/י֙ יַֽעֲקֹ֔ב וְ/יִשְׂרָאֵ֖ל מְקֹרָאִ֑/י אֲנִי הוּא֙ אֲנִ֣י רִאשׁ֔וֹן אַ֖ף אֲנִ֥י אַחֲרֽוֹן", "en": {"kjv": "Hearken unto me, O Jacob and Israel, my called; I am he; I am the first, I also am the last.", "web": "“Listen to me, O Jacob, and Israel my called: I am he; I am the first, I also am the last.", "bsb": "Listen to Me, O Jacob, and Israel, whom I have called: I am He; I am the first, and I am the last.", "asv": "Hearken unto me, O Jacob, and Israel my called: I am he; I am the first, I also am the last.", "ylt": "Hearken to me, O Jacob, and Israel, My called one, I am He, I am first, and I am last;", "dra": "Hearken to me, O Jacob, and thou Israel whom I call: I am he, I am the first, and I am the last.", "bbe": "Give ear to me, Jacob, and Israel, my loved one; I am he, I am the first and I am the last.", "geneva": "Heare me, O Iaakob and Israel, my called, I am, I am the first, and I am the last.", "wycliffe": "Jacob and Israel, whom Y clepe, here thou me; Y my silf, Y am the firste and Y am the laste.", "rotherham": "Hearken unto me O Jacob, And Israel, my called one,—I, am, the Same I, the first, yea, I, the last:", "darby": "Hearken unto me, Jacob, and [thou] Israel, my called. I [am] HE; I, the first, and I, the last.", "twenty": "", "jps": "Hearken unto Me, O Jacob, and Israel My called: I am He; I am the first, I also am the last.", "acv": "Hearken to me, O Jacob, and Israel my called: I am he. I am the first. I also am the last.", "anderson": "", "haweis": "", "noyes": "Hearken to me, O Jacob, And Israel, whom I have called! I am He, I am the first, and I the last.", "webster": "Hearken to me, O Jacob and Israel, my called; I [am] he; I [am] the first, I also [am] the last.", "vulgate": "audi me Iacob et Israhel quem ego voco ego ipse ego primus et ego novissimus;", "brenton": "Hear me, O Jacob, and Israel whom I call; I am the first, and I endure for ever."}}, {"v": 13, "ref": "48:13", "o": "אַף יָדִ/י֙ יָ֣סְדָה אֶ֔רֶץ וִֽ/ימִינִ֖/י טִפְּחָ֣ה שָׁמָ֑יִם קֹרֵ֥א אֲנִ֛י אֲלֵי/הֶ֖ם יַעַמְד֥וּ יַחְדָּֽו", "en": {"kjv": "Mine hand also hath laid the foundation of the earth, and my right hand hath spanned the heavens: when I call unto them, they stand up together.", "web": "Yes, my hand has laid the foundation of the earth, and my right hand has spread out the heavens: when I call to them, they stand up together.", "bsb": "Surely My own hand founded the earth, and My right hand spread out the heavens; when I summon them, they stand up together.", "asv": "Yea, my hand hath laid the foundation of the earth, and my right hand hath spread out the heavens: when I call unto them, they stand up together.", "ylt": "Also, My hand hath founded earth, And My right hand stretched out the heavens, I am calling unto them, they stand together.", "dra": "My hand also hath founded the earth, and my right hand hath measured the heavens: I shall call them, and they shall stand together.", "bbe": "Yes, by my hand was the earth placed on its base, and by my right hand the heavens were stretched out; at my word they take up their places.", "geneva": "Surely mine hand hath laid the foundation of the earth, and my right hand hath spanned the heaues: when I cal them, they stand vp together.", "wycliffe": "And myn hond foundide the erthe, and my riyt hond mat heuenes; Y schal clepe tho, and tho schulen stonde togidere.", "rotherham": "Surely, mine own hand, founded the earth, And, my right hand, stretched out the heavens,—While I was calling unto them, they stood forth, at once", "darby": "Yea, my hand hath laid the foundation of the earth, and my right hand hath spread abroad the heavens: I call unto them, they stand up together.", "twenty": "", "jps": "Yea, My hand hath laid the foundation of the earth, and My right hand hath spread out the heavens; when I call unto them, they stand up together.", "acv": "Yea, my hand has laid the foundation of the earth, and my right hand has spread out the heavens. When I call to them, they stand up together.", "anderson": "", "haweis": "", "noyes": "Yea, my hand hath founded the earth, And my right hand hath spread out the heavens; I called them; they stood forth together.", "webster": "My hand also hath laid the foundation of the earth, and my right hand hath spanned the heavens: [when] I call to them, they stand up together.", "vulgate": "manus quoque mea fundavit terram et dextera mea mensa est caelos ego vocabo eos et stabunt simul;", "brenton": "My hand also has founded the earth, and my right hand has fixed the sky: I will call them, and they shall stand together."}}, {"v": 14, "ref": "48:14", "o": "הִקָּבְצ֤וּ כֻלְּ/כֶם֙ וּֽ/שֲׁמָ֔עוּ מִ֥י בָ/הֶ֖ם הִגִּ֣יד אֶת אֵ֑לֶּה יְהוָ֣ה אֲהֵב֔/וֹ יַעֲשֶׂ֤ה חֶפְצ/וֹ֙ בְּ/בָבֶ֔ל וּ/זְרֹע֖/וֹ כַּשְׂדִּֽים", "en": {"kjv": "All ye, assemble yourselves, and hear; which among them hath declared these things? The Lord hath loved him: he will do his pleasure on Babylon, and his arm shall be on the Chaldeans.", "web": "“Assemble yourselves, all you, and hear; who among them has declared these things? He whom Yahweh loves shall perform his pleasure on Babylon, and his arm shall be on the Chaldeans.", "bsb": "Come together, all of you, and listen: Which of the idols has foretold these things? The LORD’s chosen ally will carry out His desire against Babylon, and His arm will be against the Chaldeans.", "asv": "Assemble yourselves, all ye, and hear; who among them hath declared these things? He whom Jehovah loveth shall perform his pleasure on Babylon, and his arm shall be on the Chaldeans.", "ylt": "Be gathered all of you, and hear, Who among them did declare these things? Jehovah hath loved him, He doth His pleasure on Babylon, And His arm is on the Chaldeans.", "dra": "Assemble yourselves together, all you, and hear: who among them hath declared these things? the Lord hath loved him, he will do his pleasure in Babylon, and his arm shall be on the Chaldeans.", "bbe": "Come together, all of you, and give ear; who among you has given news of these things? the Lord's loved one will do his pleasure with Babylon, and with the seed of the Chaldaeans.", "geneva": "All you, assemble your selues, and heare: which among them hath declared these thinges? The Lord hath loued him: he wil doe his will in Babel, and his arme shalbe against the Chaldeans.", "wycliffe": "Alle ye be gaderid togidere, and here; who of hem telde these thingis? The Lord louyde hym, he schal do his wille in Babiloyne, and his arm in Caldeis.", "rotherham": "Assemble yourselves—all of you and hear, Who among them, hath told these things? he whom Yahweh loveth, will execute—His pleasure, on Babylon, And his stroke on the Chaldeans.", "darby": "All ye, gather yourselves together, and hear: which among them hath declared these things? He whom Jehovah hath loved shall execute his pleasure on Babylon, and his arm [shall be on] the Chaldeans.", "twenty": "", "jps": "Assemble yourselves, all ye, and hear; which among them hath declared these things? He whom HaShem loveth shall perform His pleasure on Babylon, and show His arm on the Chaldeans.", "acv": "Assemble yourselves, all ye, and hear: Who among them has declared these things? He whom Jehovah loves shall perform his pleasure on Babylon, and his arm, the Chaldeans.", "anderson": "", "haweis": "", "noyes": "Assemble yourselves, all of you, and hear! Who among you hath declared these things? He whom Jehovah loveth will execute his pleasure upon Babylon, And his power upon the Chaldaeans.", "webster": "All ye, assemble yourselves and hear; who among them hath declared these [things]? The LORD hath loved him: he will do his pleasure on Babylon, and his arm [shall be on] the Chaldeans.", "vulgate": "congregamini omnes vos et audite quis de eis adnuntiavit haec Dominus dilexit eum faciet voluntatem suam in Babylone et brachium suum in Chaldeis;", "brenton": "And all shall be gathered, and shall hear: who has told them these things? Out of love to thee I have fulfilled thy desire on Babylon, to abolish the seed of the Chaldeans."}}, {"v": 15, "ref": "48:15", "o": "אֲנִ֥י אֲנִ֛י דִּבַּ֖רְתִּי אַף קְרָאתִ֑י/ו הֲבִיאֹתִ֖י/ו וְ/הִצְלִ֥יחַ דַּרְכּֽ/וֹ", "en": {"kjv": "I, even I, have spoken; yea, I have called him: I have brought him, and he shall make his way prosperous.", "web": "I, even I, have spoken; yes, I have called him; I have brought him, and he shall make his way prosperous.", "bsb": "I, even I, have spoken; yes, I have called him. I have brought him, and he will succeed in his mission.", "asv": "I, even I, have spoken; yea, I have called him; I have brought him, and he shall make his way prosperous.", "ylt": "I--I have spoken, yea, I have called him, I have brought him in, And he hath made prosperous his way.", "dra": "I, even I have spoken and called him: I have brought him, and his way is made prosperous.", "bbe": "I, even I, have given the word; I have sent for him: I have made him come, and have given effect to his undertakings.", "geneva": "I, euen I haue spoken it, and I haue called him: I haue brought him, and his way shall prosper.", "wycliffe": "Y, Y spak, and clepide hym; Y brouyte hym, and his weie was dressid.", "rotherham": "I—I, have spoken, Yea I have called him,—I have brought him in, and he shall make prosperous his way.", "darby": "I, [even] I, have spoken; yea, I have called him; I have brought him, and his way shall be prosperous.", "twenty": "", "jps": "I, even I, have spoken, yea, I have called him; I have brought him, and he shall make his way prosperous.", "acv": "I, even I, have spoken, yea, I have called him. I have brought him, and he shall make his way prosperous.", "anderson": "", "haweis": "", "noyes": "I, even I, have spoken; yea, I have called him; I have brought him, and his way shall be prosperous.", "webster": "I, [even] I, have spoken, yes, I have called him: I have brought him, and he shall make his way prosperous.", "vulgate": "ego ego locutus sum et vocavi eum adduxi eum et directa est via eius;", "brenton": "I have spoken, I have called, I have brought him, and made his way prosperous."}}, {"v": 16, "ref": "48:16", "o": "קִרְב֧וּ אֵלַ֣/י שִׁמְעוּ זֹ֗את לֹ֤א מֵ/רֹאשׁ֙ בַּ/סֵּ֣תֶר דִּבַּ֔רְתִּי מֵ/עֵ֥ת הֱיוֹתָ֖/הּ שָׁ֣ם אָ֑נִי וְ/עַתָּ֗ה אֲדֹנָ֧/י יְהוִ֛ה שְׁלָחַ֖/נִי וְ/רוּחֽ/וֹ", "en": {"kjv": "Come ye near unto me, hear ye this; I have not spoken in secret from the beginning; from the time that it was, there am I: and now the Lord God, and his Spirit, hath sent me.", "web": "“Come near to me and hear this: “From the beginning I have not spoken in secret; from the time that it was, there am I.” Now the Lord Yahweh has sent me, with his Spirit.", "bsb": "Come near to Me and listen to this: From the beginning I have not spoken in secret; from the time it happened, I was there.” And now the Lord GOD has sent me, accompanied by His Spirit.", "asv": "Come ye near unto me, hear ye this; from the beginning I have not spoken in secret; from the time that it was, there am I: and now the Lord Jehovah hath sent me, and his Spirit.", "ylt": "Come ye near unto me, hear this, Not from the beginning in secret spake I, From the time of its being, there am I, And now the Lord Jehovah hath sent me, and His Spirit.", "dra": "Come ye near unto me, and hear this: I have not spoken in secret from the beginning: from the time before it was done, I was there, and now the Lord God hath sent me, and his spirit.", "bbe": "Come near to me, and give ear to this; from the start I did not keep it secret; from the time of its coming into existence I was there: and now the Lord God has sent me, and given me his spirit.", "geneva": "Come neere vnto me: heare ye this: I haue not spoken it in secret from the beginning: from the time that the thing was, I was there, and now the Lord God and his Spirit hath sent me.", "wycliffe": "Neiye ye to me, and here ye these thingis; at the bigynnyng Y spak not in priuete; fro tyme, bifore that thingis weren maad, Y was there, and now the Lord God and his Spirit sente me.", "rotherham": "Draw ye near unto me—hear ye this, Not in advance in secret, have I spoken, From the very time it cometh into being, there, am I,—And, now, My Lord Yahweh hath sent me and his spirit.", "darby": "Come near unto me, hear ye this: I have not spoken in secret from the beginning; from the time that it was, there am I; and now the Lord Jehovah hath sent me, and his Spirit.", "twenty": "", "jps": "Come ye near unto Me, hear ye this: From the beginning I have not spoken in secret; from the time that it was, there am I; and now the L-rd GOD hath sent me, and His spirit.", "acv": "Come ye near to me, hear ye this: From the beginning I have not spoken in secret. From the time that it was, there I am. And now the lord Jehovah and his Spirit has sent me.", "anderson": "", "haweis": "", "noyes": "Draw near to me, and hear ye this! I spake not in secret from the beginning; And since it began to be, I have been there; And now hath the Lord Jehovah sent me with his spirit.", "webster": "Come ye near to me, hear ye this; I have not spoken in secret from the beginning; from the time that it was, there [am] I: and now the Lord GOD, and his Spirit, hath sent me.", "vulgate": "accedite ad me et audite hoc non a principio in abscondito locutus sum ex tempore antequam fieret ibi eram et nunc Dominus Deus misit me et spiritus eius;", "brenton": "Draw nigh to me, and hear ye these words; I have not spoken in secret from the beginning: when it took place, there was I, and now the Lord, even the Lord, and his Spirit, hath sent me."}}, {"v": 17, "ref": "48:17", "o": "כֹּֽה אָמַ֧ר יְהוָ֛ה גֹּאַלְ/ךָ֖ קְד֣וֹשׁ יִשְׂרָאֵ֑ל אֲנִ֨י יְהוָ֤ה אֱלֹהֶ֨י/ךָ֙ מְלַמֶּדְ/ךָ֣ לְ/הוֹעִ֔יל מַדְרִֽיכֲ/ךָ֖ בְּ/דֶ֥רֶךְ תֵּלֵֽךְ", "en": {"kjv": "Thus saith the Lord, thy Redeemer, the Holy One of Israel; I am the Lord thy God which teacheth thee to profit, which leadeth thee by the way that thou shouldest go.", "web": "Thus says Yahweh, your Redeemer, the Holy One of Israel: I am Yahweh your God, who teaches you to profit, who leads you by the way that you should go.", "bsb": "Thus says the LORD your Redeemer, the Holy One of Israel: “I am the LORD your God, who teaches you for your benefit, who directs you in the way you should go.", "asv": "Thus saith Jehovah, thy Redeemer, the Holy One of Israel: I am Jehovah thy God, who teacheth thee to profit, who leadeth thee by the way that thou shouldest go.", "ylt": "Thus said Jehovah, thy redeemer, The Holy One of Israel, `I am Jehovah thy God, teaching thee to profit, Causing thee to tread in the way thou goest.", "dra": "Thus saith the Lord thy redeemer, the Holy One of Israel: I am the Lord thy God that teach thee profitable things, that govern thee in the way that thou walkest.", "bbe": "The Lord who takes up your cause, the Holy One of Israel, says, I am the Lord your God, who is teaching you for your profit, guiding you by the way in which you are to go.", "geneva": "Thus saith the Lord thy redeemer, the Holy one of Israel, I am the Lord thy God, which teach thee to profite, and lead thee by the way, that thou shouldest goe.", "wycliffe": "The Lord, thin ayen biere, the hooli of Israel, seith these thingis, Y am thi Lord God, techynge thee profitable thingis, and Y gouerne thee in the weie, wher ynne thou goist.", "rotherham": "Thus saith Yahweh—Thy Redeemer, The Holy One of Israel,—I—Yahweh, am thy God, Teaching thee to profit, Guiding thee in the way thou shouldest go.", "darby": "Thus saith Jehovah, thy Redeemer, the Holy One of Israel; I [am] Jehovah thyGod, who teacheth thee for [thy] profit, who leadeth thee in the way that thou shouldest go.", "twenty": "", "jps": "Thus saith HaShem, thy Redeemer, the Holy One of Israel: I am HaShem thy G-d, who teacheth thee for thy profit, who leadeth thee by the way that thou shouldest go.", "acv": "Thus says Jehovah, thy Redeemer, the Holy One of Israel: I am Jehovah thy God, who teaches thee to profit, who leads thee by the way that thou should go.", "anderson": "", "haweis": "", "noyes": "Thus saith Jehovah, thy Redeemer, the Holy One of Israel; I am Jehovah, thy God, who teacheth thee what will profit thee; Who leadeth thee in the way thou shouldst go.", "webster": "Thus saith the LORD, thy Redeemer, the Holy One of Israel; I [am] the LORD thy God, who teacheth thee to profit, who leadeth thee by the way [that] thou shouldst go.", "vulgate": "haec dicit Dominus redemptor tuus Sanctus Israhel ego Dominus Deus tuus docens te utilia gubernans te in via qua ambulas;", "brenton": "Thus saith the Lord that delivered thee, the Holy One of Israel; I am thy God, I have shewn thee how thou shouldest find the way wherein thou shouldest walk."}}, {"v": 18, "ref": "48:18", "o": "ל֥וּא הִקְשַׁ֖בְתָּ לְ/מִצְוֺתָ֑/י וַ/יְהִ֤י כַ/נָּהָר֙ שְׁלוֹמֶ֔/ךָ וְ/צִדְקָתְ/ךָ֖ כְּ/גַלֵּ֥י הַ/יָּֽם", "en": {"kjv": "O that thou hadst hearkened to my commandments! then had thy peace been as a river, and thy righteousness as the waves of the sea:", "web": "Oh that you had listened to my commandments! then your peace would have been like a river, and your righteousness like the waves of the sea:", "bsb": "If only you had paid attention to My commandments, your peace would have been like a river, and your righteousness like waves of the sea.", "asv": "Oh that thou hadst hearkened to my commandments! then had thy peace been as a river, and thy righteousness as the waves of the sea:", "ylt": "O that thou hadst attended to My commands, Then as a river is thy peace, And thy righteousness as billows of the sea,", "dra": "O that thou hadst hearkened to my commandments: thy peace had been as a river, and thy justice as the waves of the sea,", "bbe": "If only you had given ear to my orders, then your peace would have been like a river, and your righteousness as the waves of the sea:", "geneva": "Oh that thou haddest hearkened to my commandements! then had thy prosperitie bene as the floude, and thy righteousnesse as the waues of the sea.", "wycliffe": "Y wolde that thou haddist perseyued my comaundementis, thi pees hadde be maad as flood, and thi riytfulnesse as the swolowis of the see;", "rotherham": "Oh! that thou hadst hearkened to my commandments,—Then had been, like a river, thy prosperity, And, thy righteousness, like the waves of the sea:", "darby": "Oh that thou hadst hearkened to my commandments! Then would thy peace have been as a river, and thy righteousness as the waves of the sea;", "twenty": "", "jps": "Oh that thou wouldest hearken to My commandments! then would thy peace be as a river, and thy righteousness as the waves of the sea;", "acv": "Oh that thou had hearkened to my commandments! Then thy peace would have been as a river, and thy righteousness as the waves of the sea.", "anderson": "", "haweis": "", "noyes": "O that thou wouldst hearken to my commandments! Then shall thy peace be as a river, And thy prosperity as the waves of the sea;", "webster": "O that thou hadst hearkened to my commandments! then had thy peace been as a river, and thy righteousness as the waves of the sea:", "vulgate": "utinam adtendisses mandata mea facta fuisset sicut flumen pax tua et iustitia tua sicut gurgites maris;", "brenton": "And if thou hadst hearkened to my commandments, then would thy peace have been like a river, and thy righteousness as a wave of the sea."}}, {"v": 19, "ref": "48:19", "o": "וַ/יְהִ֤י כַ/חוֹל֙ זַרְעֶ֔/ךָ וְ/צֶאֱצָאֵ֥י מֵעֶ֖י/ךָ כִּ/מְעֹתָ֑י/ו לֹֽא יִכָּרֵ֧ת וְֽ/לֹא יִשָּׁמֵ֛ד שְׁמ֖/וֹ מִ/לְּ/פָנָֽ/י", "en": {"kjv": "Thy seed also had been as the sand, and the offspring of thy bowels like the gravel thereof; his name should not have been cut off nor destroyed from before me.", "web": "your seed also had been as the sand, and the offspring of your body like its grains: his name would not be cut off nor destroyed from before me.", "bsb": "Your descendants would have been as countless as the sand, and your offspring as numerous as its grains; their name would never be cut off or eliminated from My presence.”", "asv": "thy seed also had been as the sand, and the offspring of thy bowels like the grains thereof: his name would not be cut off nor destroyed from before me.", "ylt": "And as sand is thy seed, And the offspring of thy bowels as its gravel, Not cut off nor destroyed his name before Me.", "dra": "And thy seed had been as the sand, and the offspring of thy bowels like the gravel thereof: his name should not have perished, nor have been destroyed from before my face.", "bbe": "Your seed would have been like the sand, and your offspring like the dust: your name would not be cut off or come to an end before me.", "geneva": "Thy seede also had beene as the sande, and the fruite of thy body like the grauell thereof: his name should not haue bene cut off nor destroied before me.", "wycliffe": "and thi seed hadde be as grauel, and the generacioun of thi wombe, as the litle stoonys therof; the name of it hadde not perischid, and hadde not be al to-brokun fro my face.", "rotherham": "Then had been, like the sand, thy seed, And, the offspring of thy body, like the grains thereof,—Neither cut off nor destroyed had been his name from before me.", "darby": "and thy seed would have been as the sand, and the offspring of thy bowels like the gravel thereof: their name should not have been cut off nor destroyed from before me.", "twenty": "", "jps": "Thy seed also would be as the sand, and the offspring of thy body like the grains thereof; his name would not be cut off nor destroyed from before Me.", "acv": "Thy seed also would have been as the sand, and the offspring of thy bowels like the grains of it. His name would not be cut off nor destroyed from before me.", "anderson": "", "haweis": "", "noyes": "Then shall thy posterity be as the sand, And the fruit of thy body as the offspring of the sea; Thy name shall not be cut off, nor destroyed before me.", "webster": "Thy seed also had been as the sand, and the offspring of thy bowels like its gravel; his name should not have been cut off nor destroyed from before me.", "vulgate": "et fuisset quasi harena semen tuum et stirps uteri tui ut lapilli eius non interisset et non fuisset adtritum nomen eius a facie mea;", "brenton": "Thy seed also would have been as the sand, and the offspring of thy belly as the dust of the ground: neither now shalt thou by any means be utterly destroyed, neither shall thy name perish before me."}}, {"v": 20, "ref": "48:20", "o": "צְא֣וּ מִ/בָּבֶל֮ בִּרְח֣וּ מִ/כַּשְׂדִּים֒ בְּ/ק֣וֹל רִנָּ֗ה הַגִּ֤ידוּ הַשְׁמִ֨יעוּ֙ זֹ֔את הוֹצִיא֖וּ/הָ עַד קְצֵ֣ה הָ/אָ֑רֶץ אִמְר֕וּ גָּאַ֥ל יְהוָ֖ה עַבְדּ֥/וֹ יַעֲקֹֽב", "en": {"kjv": "Go ye forth of Babylon, flee ye from the Chaldeans, with a voice of singing declare ye, tell this, utter it even to the end of the earth; say ye, The Lord hath redeemed his servant Jacob.", "web": "Leave Babylon! Flee from the Chaldeans. With a voice of singing declare, tell this, utter it even to the end of the earth: say, Yahweh has redeemed his servant Jacob.", "bsb": "Leave Babylon! Flee from the Chaldeans! Declare it with a shout of joy, proclaim it, let it go out to the ends of the earth, saying, “The LORD has redeemed His servant Jacob!”", "asv": "Go ye forth from Babylon, flee ye from the Chaldeans; with a voice of singing declare ye, tell this, utter it even to the end of the earth: say ye, Jehovah hath redeemed his servant Jacob.", "ylt": "Go out from Babylon, flee from the Chaldeans, With a voice of singing declare, Cause ye this to be heard, Bring it forth unto the end of the earth, Say, Redeemed hath Jehovah His servant Jacob.", "dra": "Come forth out of Babylon, flee ye from the Chaldeans, declare it with the voice of joy: make this to be heard, and speak it out even to the ends of the earth. Say: The Lord hath redeemed his servant Jacob.", "bbe": "Go out of Babylon, go in flight from the Chaldaeans; with the sound of song make it clear, give the news, let the word go out even to the end of the earth: say, The Lord has taken up the cause of his servant Jacob.", "geneva": "Goe yee out of Babel: flee yee from the Chaldeans, with a voice of ioy: tel and declare this: shewe it foorth to the ende of the earth: say yee, The Lord hath redeemed his seruant Iaakob.", "wycliffe": "Go ye out of Babiloyne, fle ye fro Caldeis; telle ye in the vois of ful out ioiying; make ye this herd, and bere ye it `til to the laste partis of erthe; seie ye, The Lord ayenbouyte his seruaunt Jacob.", "rotherham": "Come ye forth out of Babylon, Flee from among the Chaldeans, With triumphant voice, tell ye—let this be heard, Let it go forth as far as the end of the earth,—Say ye—Yahweh hath redeemed his servant Jacob!", "darby": "Go ye forth from Babylon, flee from the Chaldeans, with a voice of singing; declare, cause this to be heard, utter it to the end of the earth; say ye, Jehovah hath redeemed his servant Jacob.", "twenty": "", "jps": "Go ye forth from Babylon, flee ye from the Chaldeans; with a voice of singing declare ye, tell this, utter it even to the end of the earth; say ye: 'The HaShem hath redeemed His servant Jacob.", "acv": "Go ye forth from Babylon. Flee ye from the Chaldeans. With a voice of singing declare ye, tell this, utter it even to the end of the earth. Say ye, Jehovah has redeemed his servant Jacob.", "anderson": "", "haweis": "", "noyes": "Come ye forth from Babylon, flee ye from the land of the Chaldaeans with the voice of joy! Publish ye this, and make it known; Let it resound to the ends of the earth! Say: \"Jehovah hath redeemed his servant Jacob;", "webster": "Go ye forth from Babylon, flee ye from the Chaldeans, with a voice of singing declare ye, tell this, utter it [even] to the end of the earth; say ye, The LORD hath redeemed his servant Jacob.", "vulgate": "egredimini de Babylone fugite a Chaldeis in voce exultationis adnuntiate auditum facite hoc efferte illud usque ad extrema terrae dicite redemit Dominus servum suum Iacob;", "brenton": "Go forth of Babylon, thou that fleest from the Chaldeans: utter aloud a voice of joy, and let this be made known, proclaim it to the end of the earth; say ye, The Lord hath delivered his servant Jacob."}}, {"v": 21, "ref": "48:21", "o": "וְ/לֹ֣א צָמְא֗וּ בָּ/חֳרָבוֹת֙ הֽוֹלִיכָ֔/ם מַ֥יִם מִ/צּ֖וּר הִזִּ֣יל לָ֑/מוֹ וַ/יִּ֨בְקַע צ֔וּר וַ/יָּזֻ֖בוּ מָֽיִם", "en": {"kjv": "And they thirsted not when he led them through the deserts: he caused the waters to flow out of the rock for them: he clave the rock also, and the waters gushed out.", "web": "They didn’t thirst when he led them through the deserts; he caused the waters to flow out of the rock for them; he split the rock also, and the waters gushed out.", "bsb": "They did not thirst when He led them through the deserts; He made water flow for them from the rock; He split the rock, and water gushed out.", "asv": "And they thirsted not when he led them through the deserts; he caused the waters to flow out of the rock for them; he clave the rock also, and the waters gushed out.", "ylt": "And they have not thirsted in waste places, He hath caused them to go on, Waters from a rock he hath caused to flow to them, Yea, he cleaveth a rock, and flow do waters.", "dra": "They thirsted not in the desert, when he led them out: he brought forth water out of the rock for them, and he clove the rock, and the waters gushed out.", "bbe": "They had no need of water when he was guiding them through the waste lands: he made water come out of the rock for them: the rock was parted and the waters came flowing out.", "geneva": "And they were not thirstie: hee led them through the wildernesse: hee caused the waters to flowe out of the rocke for them: for he claue the rocke, and the water gushed out.", "wycliffe": "Thei thirstiden not in desert, whanne he ladde hem out; he brouyte forth to hem watir of a stoon, and he departide the stoon, and watris flowiden.", "rotherham": "And they thirsted not, when, through dry places, he led them, Waters out of the rock, caused he to flow out to them,—Yea be cleft a rock and, there gushed out waters:", "darby": "And they thirsted not when he led them through the deserts; he caused the waters to flow out of the rock for them; yea, he clave the rock, and the waters gushed out.", "twenty": "", "jps": "And they thirsted not when He led them through the deserts; He caused the waters to flow out of the rock for them; He cleaved the rock also, and the waters gushed out.'", "acv": "And they did not thirst when he led them through the deserts. He caused the waters to flow out of the rock for them. He also split the rock, and the waters gushed out.", "anderson": "", "haweis": "", "noyes": "They thirst not in the deserts through which he leadeth them; Waters from the rock he causeth to flow for them; He cleaveth the rock, and the waters gush forth.", "webster": "And they thirsted not, [when] he led them through the deserts: he caused the waters to flow out of the rock for them: he cleaved the rock also, and the waters gushed out.", "vulgate": "non sitierunt in deserto cum educeret eos aquam de petra produxit eis et scidit petram et fluxerunt aquae;", "brenton": "And if they shall thirst, he shall lead them through the desert; he shall bring forth water to them out of the rock: the rock shall be cloven, and the water shall flow forth, and my people shall drink."}}, {"v": 22, "ref": "48:22", "o": "אֵ֣ין שָׁל֔וֹם אָמַ֥ר יְהוָ֖ה לָ/רְשָׁעִֽים", "en": {"kjv": "There is no peace, saith the Lord, unto the wicked.", "web": "“There is no peace”, says Yahweh, “for the wicked.”", "bsb": "“There is no peace,” says the LORD, “for the wicked.”", "asv": "There is no peace, saith Jehovah, to the wicked.", "ylt": "There is no peace, said Jehovah, to the wicked!", "dra": "There is no peace to the wicked, saith the Lord.", "bbe": "There is no peace, says the Lord, for the evil-doers.", "geneva": "There is no peace, sayeth the Lord, vnto the wicked.", "wycliffe": "Pees is not to wickid men, seith the Lord.", "rotherham": "No well-being, saith Yahweh to the lawless,", "darby": "There is no peace, saith Jehovah, unto the wicked.", "twenty": "", "jps": "There is no peace, saith HaShem concerning the wicked.", "acv": "There is no peace, says Jehovah, to the wicked.", "anderson": "", "haweis": "", "noyes": "There is no peace, saith Jehovah, for the wicked.\"", "webster": "[There is] no peace, saith the LORD, to the wicked.", "vulgate": "non est pax dicit Dominus impiis;", "brenton": "There is no joy, saith the Lord, to the ungodly."}}]}, {"c": 49, "verses": [{"v": 1, "ref": "49:1", "o": "שִׁמְע֤וּ אִיִּים֙ אֵלַ֔/י וְ/הַקְשִׁ֥יבוּ לְאֻמִּ֖ים מֵ/רָח֑וֹק יְהוָה֙ מִ/בֶּ֣טֶן קְרָאָ֔/נִי מִ/מְּעֵ֥י אִמִּ֖/י הִזְכִּ֥יר שְׁמִֽ/י", "en": {"kjv": "Listen, O isles, unto me; and hearken, ye people, from far; The Lord hath called me from the womb; from the bowels of my mother hath he made mention of my name.", "web": "Listen, islands, to me; and listen, you peoples, from far: Yahweh has called me from the womb; from the bowels of my mother has he made mention of my name:", "bsb": "Listen to Me, O islands; pay attention, O distant peoples: The LORD called Me from the womb; from the body of My mother He named Me.", "asv": "Listen, O isles, unto me; and hearken, ye peoples, from far: Jehovah hath called me from the womb; from the bowels of my mother hath he made mention of my name:", "ylt": "Hearken, O isles, unto me, And attend, O peoples, from afar, Jehovah from the womb hath called me, From the bowels of my mother He hath made mention of my name.", "dra": "Give ear, ye islands, and hearken, ye people from afar. The Lord hath called me from the womb, from the bowels of my mother he hath been mindful of my name.", "bbe": "Give ear, O sea-lands, to me; and take note, you peoples from far: I have been marked out by the Lord from the first; when I was still in my mother's body, he had my name in mind:", "geneva": "Hear yee me, O yles, and hearken, yee people from farre. The Lord hath called me from the wombe, and made mention of my name from my mothers bellie.", "wycliffe": "Ilis, here ye, and puplis afer, perseyue ye; the Lord clepide me fro the wombe, he thouyte on my name fro the wombe of my modir.", "rotherham": "Hearken, ye Coastlands, unto me, And give ear ye peoples afar off,—Yahweh, called me, from my birth, From my nativity, made he mention of my name;", "darby": "Listen, O isles, unto me; and hearken, ye peoples from afar. Jehovah hath called me from the womb; from the bowels of my mother hath he made mention of my name.", "twenty": "", "jps": "Listen, O isles, unto me, and hearken, ye peoples, from far: HaShem hath called me from the womb, from the bowels of my mother hath He made mention of my name;", "acv": "Listen, O isles, to me, and hearken, ye peoples from far. Jehovah has called me from the womb. From the bowels of my mother he has made mention of my name.", "anderson": "", "haweis": "", "noyes": "Listen to me, ye distant lands! Attend, ye nations from afar! Jehovah called me at my birth; In my very childhood he called me by name.", "webster": "Listen to me, O Isles; and hearken, ye people, from far; The LORD hath called me from the womb; from the bowels of my mother hath he made mention of my name.", "vulgate": "audite insulae et adtendite populi de longe Dominus ab utero vocavit me de ventre matris meae recordatus est nominis mei;", "brenton": "Hearken to me, ye islands; and attend, ye Gentiles; after a long time it shall come to pass, saith the Lord: from my mother's womb he has called my name:"}}, {"v": 2, "ref": "49:2", "o": "וַ/יָּ֤שֶׂם פִּ/י֙ כְּ/חֶ֣רֶב חַדָּ֔ה בְּ/צֵ֥ל יָד֖/וֹ הֶחְבִּיאָ֑/נִי וַ/יְשִׂימֵ֨/נִי֙ לְ/חֵ֣ץ בָּר֔וּר בְּ/אַשְׁפָּת֖/וֹ הִסְתִּירָֽ/נִי", "en": {"kjv": "And he hath made my mouth like a sharp sword; in the shadow of his hand hath he hid me, and made me a polished shaft; in his quiver hath he hid me;", "web": "and he has made my mouth like a sharp sword; in the shadow of his hand, he has hidden me: and he has made me a polished shaft; in his quiver has he kept me close:", "bsb": "He made My mouth like a sharp sword; He hid Me in the shadow of His hand. He made Me like a polished arrow; He hid Me in His quiver.", "asv": "and he hath made my mouth like a sharp sword; in the shadow of his hand hath he hid me: and he hath made me a polished shaft; in his quiver hath he kept me close:", "ylt": "And he maketh my mouth as a sharp sword, In the shadow of His hand He hath hid me, And He maketh me for a clear arrow, In His quiver He hath hid me.", "dra": "And he hath made my mouth like a sharp sword: in the shadow of his hand he hath protected me, and hath made me as a chosen arrow: in his quiver he hath hidden me.", "bbe": "And he has made my mouth like a sharp sword, in the shade of his hand he has kept me; and he has made me like a polished arrow, keeping me in his secret place;", "geneva": "And hee hath made my mouth like a sharpe sworde: vnder the shadowe of his hande hath he hid mee, and made me a chosen shafte, and hid me in his quiuer,", "wycliffe": "And he hath set my mouth as a scharp swerd, he defendide me in the schadewe of his hond, and settide me as a chosun arowe; he hidde me in his arowe caas,", "rotherham": "And he made my mouth, like a sharp sword, In the shadow of his hand, he concealed me,—And made of me a polished arrow, In his quiver, he hid me;", "darby": "And he hath made my mouth like a sharp sword, he hath concealed me under the shadow of his hand, and he hath made me a polished shaft: in his quiver hath he hidden me.", "twenty": "", "jps": "And He hath made my mouth like a sharp sword, in the shadow of His hand hath He hid me; and He hath made me a polished shaft, in His quiver hath He concealed me;", "acv": "And he has made my mouth like a sharp sword. He has hid me in the shadow of his hand, and he has made me a polished shaft. He has kept me close in his quiver.", "anderson": "", "haweis": "", "noyes": "He made my mouth like a sharp sword; In the shadow of his hand did he hide me. He made me a polished shaft; In his quiver did he hide me.", "webster": "And he hath made my mouth like a sharp sword; in the shade of his hand hath he hid me, and made me a polished shaft; in his quiver hath he hid me;", "vulgate": "et posuit os meum quasi gladium acutum in umbra manus suae protexit me et posuit me sicut sagittam electam in faretra sua abscondit me;", "brenton": "and he has made my mouth as a sharp sword, and he has hid me under the shadow of his hand; he has made me as a choice shaft, and he has hid me in his quiver;"}}, {"v": 3, "ref": "49:3", "o": "וַ/יֹּ֥אמֶר לִ֖/י עַבְדִּ/י אָ֑תָּה יִשְׂרָאֵ֕ל אֲשֶׁר בְּ/ךָ֖ אֶתְפָּאָֽר", "en": {"kjv": "And said unto me, Thou art my servant, O Israel, in whom I will be glorified.", "web": "and he said to me, “You are my servant; Israel, in whom I will be glorified.”", "bsb": "He said to Me, “You are My Servant, Israel, in whom I will display My glory.”", "asv": "and he said unto me, Thou art my servant; Israel, in whom I will be glorified.", "ylt": "And He saith to me, `My servant Thou art, O Israel, In whom I beautify Myself.'", "dra": "And he said to me: Thou art my servant Israel, for in thee will I glory.", "bbe": "And he said to me, You are my servant, Israel, in whom my glory will be seen;", "geneva": "And sayd vnto me, Thou art my seruaunt, Israel, for I will be glorious in thee.", "wycliffe": "and seide to me, Israel, thou art my seruaunt, for Y schal haue glorie in thee.", "rotherham": "And said to me My Servant, thou art,—Israel, in whom I will get myself glory.", "darby": "And he said unto me, Thou art my servant, Israel, in whom I will glorify myself.", "twenty": "", "jps": "And He said unto me: 'Thou art My servant, Israel, in whom I will be glorified.'", "acv": "And he said to me, Thou are my servant, Israel, in whom I will be glorified.", "anderson": "", "haweis": "", "noyes": "He said to me, Thou art my servant; Israel, in whom I will be glorified.", "webster": "And said to me, Thou [art] my servant, O Israel, in whom I will be glorified.", "vulgate": "et dixit mihi servus meus es tu Israhel quia in te gloriabor;", "brenton": "and said to me, Thou art my servant, O Israel, and in thee I will be glorified."}}, {"v": 4, "ref": "49:4", "o": "וַ/אֲנִ֤י אָמַ֨רְתִּי֙ לְ/רִ֣יק יָגַ֔עְתִּי לְ/תֹ֥הוּ וְ/הֶ֖בֶל כֹּחִ֣/י כִלֵּ֑יתִי אָכֵן֙ מִשְׁפָּטִ֣/י אֶת יְהוָ֔ה וּ/פְעֻלָּתִ֖/י אֶת אֱלֹהָֽ/י", "en": {"kjv": "Then I said, I have laboured in vain, I have spent my strength for nought, and in vain: yet surely my judgment is with the Lord, and my work with my God.", "web": "But I said, “I have labored in vain, I have spent my strength for nothing and vanity; yet surely the justice due to me is with Yahweh, and my reward with my God.”", "bsb": "But I said, “I have labored in vain, I have spent My strength in futility and vanity; yet My vindication is with the LORD, and My reward is with My God.”", "asv": "But I said, I have labored in vain, I have spent my strength for nought and vanity; yet surely the justice due to me is with Jehovah, and my recompense with my God.", "ylt": "And I said, `For a vain thing I laboured, For emptiness and vanity my power I consumed, But my judgment is with Jehovah, And my wage with my God.", "dra": "And I said: I have laboured in vain, I have spent my strength without cause and in vain: therefore my judgment is with the Lord, and my work with my God.", "bbe": "And I said, I have undergone weariness for nothing, I have given my strength for no purpose or profit: but still the Lord will take up my cause, and my God will give me my reward.", "geneva": "And I said, I haue labored in vaine: I haue spent my strength in vaine and for nothing: but my iudgement is with the Lord, and my woorke with my God.", "wycliffe": "And Y seide, Y trauelide in veyn, Y wastide my strengthe with out cause, and veynli; therfor my doom is with the Lord, and my werk is with my God.", "rotherham": "But I, said, To no purpose, have I toiled, For waste and mist—my vigour, have I spent,—Surely, my vindication, is, with, Yahweh, And, my recompence, with my God.", "darby": "— And I said, I have laboured in vain, I have spent my strength for nought and in vain; nevertheless my judgment is with Jehovah, and my work with myGod.", "twenty": "", "jps": "But I said: 'I have laboured in vain, I have spent my strength for nought and vanity; yet surely my right is with HaShem, and my recompense with my G-d.'", "acv": "But I said, I have labored in vain. I have spent my strength for nothing and vanity. Yet surely the justice due to me is with Jehovah, and my recompense with my God.", "anderson": "", "haweis": "", "noyes": "Then I said, I have labored in vain; For naught, for vanity, have I spent my strength; Yet my cause is with Jehovah, And my reward with my God.", "webster": "Then I said, I have labored in vain, I have spent my strength for naught, and in vain; [yet] surely my judgment [is] with the LORD, and my work with my God.", "vulgate": "et ego dixi in vacuum laboravi sine causa et vane fortitudinem meam consumpsi ergo iudicium meum cum Domino et opus meum cum Deo meo;", "brenton": "Then I said, I have laboured in vain, I have given my strength for vanity and for nothing: therefore is my judgment with the Lord, and my labour before my God."}}, {"v": 5, "ref": "49:5", "o": "וְ/עַתָּ֣ה אָמַ֣ר יְהוָ֗ה יֹצְרִ֤/י מִ/בֶּ֨טֶן֙ לְ/עֶ֣בֶד ל֔/וֹ לְ/שׁוֹבֵ֤ב יַֽעֲקֹב֙ אֵלָ֔י/ו וְ/יִשְׂרָאֵ֖ל לא ל֣/וֹ יֵאָסֵ֑ף וְ/אֶכָּבֵד֙ בְּ/עֵינֵ֣י יְהוָ֔ה וֵ/אלֹהַ֖/י הָיָ֥ה עֻזִּֽ/י", "en": {"kjv": "And now, saith the Lord that formed me from the womb to be his servant, to bring Jacob again to him, Though Israel be not gathered, yet shall I be glorious in the eyes of the Lord, and my God shall be my strength.", "web": "Now says Yahweh who formed me from the womb to be his servant, to bring Jacob again to him, and that Israel be gathered to him (for I am honorable in the eyes of Yahweh, and my God has become my strength);", "bsb": "And now says the LORD, who formed Me from the womb to be His Servant, to bring Jacob back to Him, that Israel might be gathered to Him— for I am honored in the sight of the LORD, and My God is My strength—", "asv": "And now saith Jehovah that formed me from the womb to be his servant, to bring Jacob again to him, and that Israel be gathered unto him (for I am honorable in the eyes of Jehovah, and my God is become my strength);", "ylt": "And now, said Jehovah, who is forming me from the belly for a servant to Him, To bring back Jacob unto Him, (Though Israel is not gathered, Yet I am honoured in the eyes of Jehovah, And my God hath been my strength.)", "dra": "And now saith the Lord, that formed me from the womb to be his servant, that I may bring back Jacob unto him, and Israel will not be gathered together: and I am glorified in the eyes of the Lord, and my God is made my strength.", "bbe": "And now, says the Lord, who made me his servant when I was still in my mother's body, so that I might make Jacob come back to him, and so that Israel might come together to him: and I was honoured in the eyes of the Lord, and my God became my strength.", "geneva": "And now sayeth the Lord, that formed me from the wombe to be his seruaunt, that I may bring Iaakob againe to him (though Israel be not gathered, yet shall I bee glorious in the eyes of the Lord: and my God shall be my strength)", "wycliffe": "And now the Lord, formynge me a seruaunt to hym silf fro the wombe, seith these thingis, that Y brynge ayen Jacob to hym. And Israel schal not be gaderid togidere; and Y am glorified in the iyen of the Lord, and my God is maad my strengthe.", "rotherham": "Now, therefore, said Yahweh—Fashioning me from birth To be Servant to him, To restore Jacob unto him, And that, Israel, unto him, might be gathered And I be honourable in the eyes of Yahweh, And, my God, be proved to have been my strength,", "darby": "And now, saith Jehovah, that formed me from the womb to be his servant, that I should bring Jacob again to him; (though Israel be not gathered, yet shall I be glorified in the eyes of Jehovah, and myGod shall be my strength;)", "twenty": "", "jps": "And now saith HaShem that formed me from the womb to be His servant, to bring Jacob back to Him, and that Israel be gathered unto Him--for I am honourable in the eyes of HaShem, and my G-d is become my strength--", "acv": "And now says Jehovah who formed me from the womb to be his servant, to bring Jacob again to him, and that Israel be gathered to him (for I am honorable in the eyes of Jehovah, and my God has become my strength),", "anderson": "", "haweis": "", "noyes": "And now thus saith Jehovah, Who formed me from my birth to be his servant To bring Jacob to him again, And that Israel might be gathered to him,—For I am honored in the eyes of Jehovah, And my God is my strength,—", "webster": "And now, saith the LORD that formed me from the womb [to be] his servant, to bring Jacob again to him, Though Israel be not gathered, yet shall I be glorious in the eyes of the LORD, and my God shall be my strength.", "vulgate": "et nunc dicit Dominus formans me ex utero servum sibi ut reducam Iacob ad eum et Israhel non congregabitur et glorificatus sum in oculis Domini et Deus meus factus est fortitudo mea;", "brenton": "And now, thus saith the Lord that formed me from the womb to be his own servant, to gather Jacob to him and Israel. I shall be gathered and glorified before the Lord, and my God shall be my strength."}}, {"v": 6, "ref": "49:6", "o": "וַ/יֹּ֗אמֶר נָקֵ֨ל מִֽ/הְיוֹתְ/ךָ֥ לִ/י֙ עֶ֔בֶד לְ/הָקִים֙ אֶת שִׁבְטֵ֣י יַעֲקֹ֔ב ו/נצירי וּ/נְצוּרֵ֥י יִשְׂרָאֵ֖ל לְ/הָשִׁ֑יב וּ/נְתַתִּ֨י/ךָ֙ לְ/א֣וֹר גּוֹיִ֔ם לִֽ/הְי֥וֹת יְשׁוּעָתִ֖/י עַד קְצֵ֥ה הָ/אָֽרֶץ", "en": {"kjv": "And he said, It is a light thing that thou shouldest be my servant to raise up the tribes of Jacob, and to restore the preserved of Israel: I will also give thee for a light to the Gentiles, that thou mayest be my salvation unto the end of the earth.", "web": "yes, he says, “It is too light a thing that you should be my servant to raise up the tribes of Jacob, and to restore the preserved of Israel: I will also give you for a light to the nations, that you may be my salvation to the end of the earth.”", "bsb": "He says: “It is not enough for You to be My Servant, to raise up the tribes of Jacob, and to restore the protected ones of Israel. I will also make You a light for the nations, to bring My salvation to the ends of the earth.”", "asv": "yea, he saith, It is too light a thing that thou shouldest be my servant to raise up the tribes of Jacob, and to restore the preserved of Israel: I will also give thee for a light to the Gentiles, that thou mayest be my salvation unto the end of the earth.", "ylt": "And He saith, `It hath been a light thing That thou art to Me for a servant To raise up the tribes of Jacob, And the preserved of Israel to bring back, And I have given thee for a light of nations, To be My salvation unto the end of the earth.'", "dra": "And he said: It is a small thing that thou shouldst be my servant to raise up the tribes of Jacob, and to convert the dregs of Israel. Behold, I have given thee to be the light of the Gentiles, that thou mayst be my salvation even to the farthest part of the earth.", "bbe": "It is not enough for one who is my servant to put the tribes of Jacob again in their place, and to get back those of Israel who have been sent away: my purpose is to give you as a light to the nations, so that you may be my salvation to the end of the earth.", "geneva": "And hee sayde, It is a small thing that thou shouldest be my seruaunt, to raise vp the tribes of Iaakob, and to restore the desolations of Israel: I will also giue thee for a light of the Gentiles, that thou maiest bee my saluation vnto the ende of the worlde.", "wycliffe": "And he seyde, It is litil, that thou be a seruaunt to me, to reise the lynages of Jacob, and to conuerte the drastis of Israel; Y yaf thee in to the liyt of hethene men, that thou be myn helthe `til to the laste part of erthe.", "rotherham": "Yea he said—It is too small a thing, for being my Servant, That thou shouldest raise up the tribes of Jacob, And the preserved of Israel, shouldst restore,—So I will give thee to become a light of nations, That, my salvation, may reach as far as the end of the earth.", "darby": "— and he saith, It is a small thing that thou shouldest be my servant to raise up the tribes of Jacob, and to restore the preserved of Israel; I have even given thee for a light of the nations, that thou mayest be my salvation unto the end of the earth.", "twenty": "", "jps": "Yea, He saith: 'It is too light a thing that thou shouldest be My servant to raise up the tribes of Jacob, and to restore the offspring of Israel; I will also give thee for a light of the nations, that My salvation may be unto the end of the earth.'", "acv": "yea, he says, It is too light a thing that thou should be my servant to raise up the tribes of Jacob, and to restore the preserved of Israel. I will also give thee for a light to the Gentiles, that thou may be my salvation to the end of the earth.", "anderson": "", "haweis": "", "noyes": "He said, It is a small tiling that thou shouldst be my servant, To raise up the tribes of Jacob, And to restore the preserved of Israel; I will also make thee the light of the nations, That my salvation may reach the ends of the earth.", "webster": "And he said, It is a light thing that thou shouldst be my servant to raise up the tribes of Jacob, and to restore the preserved of Israel: I will also give thee for a light to the Gentiles, that thou mayest be my salvation to the end of the earth.", "vulgate": "et dixit parum est ut sis mihi servus ad suscitandas tribus Iacob et feces Israhel convertendas dedi te in lucem gentium ut sis salus mea usque ad extremum terrae;", "brenton": "And he said to me, It is a great thing for thee to be called my servant, to establish the tribes of Jacob, and to recover the dispersion of Israel: behold, I have given thee for the covenant of a race, for a light of the Gentiles, that thou shouldest be for salvation to the end of the earth."}}, {"v": 7, "ref": "49:7", "o": "כֹּ֣ה אָֽמַר יְהוָה֩ גֹּאֵ֨ל יִשְׂרָאֵ֜ל קְדוֹשׁ֗/וֹ לִ/בְזֹה נֶ֜פֶשׁ לִ/מְתָ֤עֵֽב גּוֹי֙ לְ/עֶ֣בֶד מֹשְׁלִ֔ים מְלָכִים֙ יִרְא֣וּ וָ/קָ֔מוּ שָׂרִ֖ים וְ/יִֽשְׁתַּחֲוּ֑וּ לְמַ֤עַן יְהוָה֙ אֲשֶׁ֣ר נֶאֱמָ֔ן קְדֹ֥שׁ יִשְׂרָאֵ֖ל וַ/יִּבְחָרֶֽ/ךָּ", "en": {"kjv": "Thus saith the Lord, the Redeemer of Israel, and his Holy One, to him whom man despiseth, to him whom the nation abhorreth, to a servant of rulers, Kings shall see and arise, princes also shall worship, because of the Lord that is faithful, and the Holy One of Israel, and he shall choose thee.", "web": "Thus says Yahweh, the Redeemer of Israel, and his Holy One, to him whom man despises, to him whom the nation abhors, to a servant of rulers: “Kings shall see and arise; princes, and they shall worship; because of Yahweh who is faithful, even the Holy One of Israel, who has chosen you.”", "bsb": "Thus says the LORD, the Redeemer and Holy One of Israel, to Him who was despised and abhorred by the nation, to the Servant of rulers: “Kings will see You and rise, and princes will bow down, because of the LORD, who is faithful, the Holy One of Israel, who has chosen You.”", "asv": "Thus saith Jehovah, the Redeemer of Israel, and his Holy One, to him whom man despiseth, to him whom the nation abhorreth, to a servant of rulers: Kings shall see and arise; princes, and they shall worship; because of Jehovah that is faithful, even the Holy One of Israel, who hath chosen thee.", "ylt": "Thus said Jehovah, Redeemer of Israel, His Holy One, To the despised in soul, To the abominated of a nation, To the servant of rulers: `Kings see, and have risen, princes, and worship, For the sake of Jehovah, who is faithful, The Holy of Israel, and He chooseth thee.'", "dra": "Thus saith the Lord the redeemer of Israel, his Holy One, to the soul that is despised, to the nation that is abhorred, to the servant of rulers: Kings shall see, and princes shall rise up, and adore for the Lord's sake, because he is faithful, and for the Holy One of Israel, who hath chosen thee.", "bbe": "The Lord who takes up Israel's cause, even his Holy One, says to him whom men make sport of, who is hated by the nations, a servant of rulers: Kings will see and get up from their places, and chiefs will give worship: because of the Lord who keeps faith; even the Holy One of Israel who has taken you for himself.", "geneva": "Thus sayeth the Lord the redeemer of Israel, and his Holie one, to him that is despised in soule, to a nation that is abhorred, to a seruaunt of rulers, Kinges shall see, and arise, and princes shall worship, because of the Lord, that is faithfull: and ye Holy one of Israel, which hath chosen thee.", "wycliffe": "The Lord, ayenbiere of Israel, the hooli therof, seith these thingis to a dispisable soule, and to a folk had in abhomynacioun, to the seruaunt of lordis, Kyngis schulen se, and princes schulen rise togidere, and schulen worschipe, for the Lord, for he is feithful, and for the hooli of Israel, that chees thee.", "rotherham": "Thus, saith Yahweh—the Redeemer of Israel, his Holy One To him that is despised of the soul, To the abhorred of the nation To the servant of rulers, Kings, shall see and arise, Princes, lo! they have bowed themselves down,—Because of Yahweh, who is faithful, The Holy One of Israel, lo! he hath chosen thee.", "darby": "Thus saith Jehovah, the Redeemer of Israel, his Holy One, to him whom man despiseth, to him whom the nation abhorreth, to the servant of rulers: Kings shall see and arise, princes, and they shall worship, because of Jehovah who is faithful, the Holy One of Israel, who hath chosen thee.", "twenty": "", "jps": "Thus saith HaShem, the Redeemer of Israel, his Holy One, to him who is despised of men, to him who is abhorred of nations, to a servant of rulers: kings shall see and arise, princes, and they shall prostrate themselves; because of HaShem that is faithful, even the Holy One of Israel, who hath chosen thee.", "acv": "Thus says Jehovah, the Redeemer of Israel, and his Holy One, to him whom man despises, to him whom the nation abhors, to a servant of rulers. Kings shall see and arise, rulers, and they shall worship, because of Jehovah who is faithful, even the Holy One of Israel, who has chosen thee.", "anderson": "", "haweis": "", "noyes": "Thus saith Jehovah, the Redeemer of Israel, his Holy One, To him that is despised by men, abhorred by the people, To the servant of tyrants; Kings shall see, and stand up, Princes, and they shall pay homage, On account of Jehovah, who is faithful, The Holy One of Israel, who hath chosen thee.", "webster": "Thus saith the LORD, the Redeemer of Israel, [and] his Holy One, to him whom man despiseth, to him whom the nation abhorreth, to a servant of rulers, kings shall see and arise, princes also shall worship, because of the LORD that is faithful, [and] the Holy One of Israel, and he shall choose thee.", "vulgate": "haec dicit Dominus redemptor Israhel Sanctus eius ad contemptibilem animam ad abominatam gentem ad servum dominorum reges videbunt et consurgent principes et adorabunt propter Dominum quia fidelis est et Sanctum Israhel qui elegit te;", "brenton": "Thus saith the Lord that delivered thee, the God of Israel, Sanctify him that despises his life, him that is abhorred by the nations that are the servants of princes: kings shall behold him, and princes shall arise, and shall worship him, for the Lord's sake: for the Holy One of Israel is faithful, and I have chosen thee."}}, {"v": 8, "ref": "49:8", "o": "כֹּ֣ה אָמַ֣ר יְהוָ֗ה בְּ/עֵ֤ת רָצוֹן֙ עֲנִיתִ֔י/ךָ וּ/בְ/י֥וֹם יְשׁוּעָ֖ה עֲזַרְתִּ֑י/ךָ וְ/אֶצָּרְ/ךָ֗ וְ/אֶתֶּנְ/ךָ֙ לִ/בְרִ֣ית עָ֔ם לְ/הָקִ֣ים אֶ֔רֶץ לְ/הַנְחִ֖יל נְחָל֥וֹת שֹׁמֵמֽוֹת", "en": {"kjv": "Thus saith the Lord, In an acceptable time have I heard thee, and in a day of salvation have I helped thee: and I will preserve thee, and give thee for a covenant of the people, to establish the earth, to cause to inherit the desolate heritages;", "web": "Thus says Yahweh, “In an acceptable time have I answered you, and in a day of salvation have I helped you; and I will preserve you, and give you for a covenant of the people, to raise up the land, to make them inherit the desolate heritage:", "bsb": "This is what the LORD says: “In the time of favor I will answer You, and in the day of salvation I will help You; I will keep You and appoint You to be a covenant for the people, to restore the land, to apportion its desolate inheritances,", "asv": "Thus saith Jehovah, In an acceptable time have I answered thee, and in a day of salvation have I helped thee; and I will preserve thee, and give thee for a covenant of the people, to raise up the land, to make them inherit the desolate heritages;", "ylt": "Thus said Jehovah: `In a time of good pleasure I answered thee, And in a day of salvation I helped thee, And I keep thee, and give thee, For a covenant of the people, To establish the earth, To cause to inherit desolate inheritances.", "dra": "Thus saith the Lord: In an acceptable time I have heard thee, and in the day of salvation I have helped thee: and I have preserved thee, and given thee to be a covenant of the people, that thou mightest raise up the earth, and possess the inheritances that were destroyed:", "bbe": "This is the word of the Lord: I have given ear to you at a good time, and I have been your helper in a day of salvation: and I will keep you safe, and will make you a glory for the people, putting the land in order, and giving them the heritages which now are waste;", "geneva": "Thus sayeth the Lord, In an acceptable time haue I heard thee, and in a day of saluation haue I helped thee: and I will preserue thee, and wil giue thee for a couenant of ye people, that thou maiest raise vp the earth, and obtaine the inheritance of the desolate heritages:", "wycliffe": "The Lord seith these thingis, In a plesaunt tyme Y herde thee, and in the dai of helthe Y helpide thee; and Y kepte thee, and yaf thee in to a bonde of pees of the puple, that thou schuldist reise the erthe, and haue in possessioun eritagis, `that ben distried;", "rotherham": "Thus, saith Yahweh—In a time of acceptance, have I answered thee, In a day of salvation, have I helped thee,—That I may preserve thee And give thee as the covenant of a people, To establish the land, To bring into possession the desolate heritages;", "darby": "Thus saith Jehovah: In a time of acceptance have I answered thee, and in the day of salvation have I helped thee; and I will preserve thee, and give thee for a covenant of the people, to establish the land, to cause to inherit the desolate heritages;", "twenty": "", "jps": "Thus saith HaShem: in an acceptable time have I answered thee, and in a day of salvation have I helped thee; and I will preserve thee, and give thee for a covenant of the people, to raise up the land, to cause to inherit the desolate heritages;", "acv": "Thus says Jehovah, In an acceptable time I have heard thee, and in a day of salvation I have helped thee. And I will preserve thee, and give thee for a covenant of the people, to raise up the land, to make them inherit the desolate heritages,", "anderson": "", "haweis": "", "noyes": "Thus saith Jehovah; In the time of favor will I hear thee; In the day of deliverance will I help thee; I will preserve thee, and make thee a mediator for the people, To restore the land, to distribute the desolated inheritances;", "webster": "Thus saith the LORD, In an acceptable time have I heard thee, and in a day of salvation have I helped thee: and I will preserve thee, and give thee for a covenant of the people, to establish the earth, to cause to inherit the desolate heritages:", "vulgate": "haec dicit Dominus in tempore placito exaudivi te et in die salutis auxiliatus sum tui et servavi te et dedi te in foedus populi ut suscitares terram et possideres hereditates dissipatas;", "brenton": "Thus saith the Lord, In an acceptable time have I heard thee, and in a day of salvation have I succored thee: and I have formed thee, and given thee for a covenant of the nations, to establish the earth, and to cause to inherit the desert heritages:"}}, {"v": 9, "ref": "49:9", "o": "לֵ/אמֹ֤ר לַֽ/אֲסוּרִים֙ צֵ֔אוּ לַ/אֲשֶׁ֥ר בַּ/חֹ֖שֶׁךְ הִגָּל֑וּ עַל דְּרָכִ֣ים יִרְע֔וּ וּ/בְ/כָל שְׁפָיִ֖ים מַרְעִיתָֽ/ם", "en": {"kjv": "That thou mayest say to the prisoners, Go forth; to them that are in darkness, Shew yourselves. They shall feed in the ways, and their pastures shall be in all high places.", "web": "saying to those who are bound, ‘Come out!’; to those who are in darkness, ‘Show yourselves!’ “They shall feed in the ways, and on all bare heights shall be their pasture.", "bsb": "to say to the prisoners, ‘Come out,’ and to those in darkness, ‘Show yourselves.’ They will feed along the pathways, and find pasture on every barren hill.", "asv": "saying to them that are bound, Go forth; to them that are in darkness, Show yourselves. They shall feed in the ways, and on all bare heights shall be their pasture.", "ylt": "To say to the bound, Go out, To those in darkness, Be uncovered. On the ways they feed, And in all high places is their pasture.", "dra": "That thou mightest say to them that are bound: Come forth: and to them that are in darkness: Shew yourselves. They shall feed in the ways, and their pastures shall be in every plain.", "bbe": "Saying to those who are in chains, Go free; to those who are in the dark, Come out into the light. They will get food by the way wherever they go, and have grass-lands on all the dry mountain-tops.", "geneva": "That thou maiest say to the prisoners, Goe foorth: and to them that are in darkenesse, Shewe your selues: they shall feede in the waies, and their pastures shall bee in all the toppes of the hilles.", "wycliffe": "that thou schuldist seie to hem that ben boundun, Go ye out, and to hem that ben in derknessis, Be ye schewid. Thei schulen be fed on weies, and the lesewis of hem schulen be in alle pleyn thingis.", "rotherham": "Saying To them who are bound Go forth, To them who are in darkness, Shew yourselves,—By the roads, shall they graze, And on all bare places, shall be their pasture:", "darby": "saying to the prisoners, Go forth; to them that are in darkness, Shew yourselves. They shall feed in the ways, and their pasture shall be on all bare hills.", "twenty": "", "jps": "Saying to the prisoners: 'Go forth'; to them that are in darkness: 'Show yourselves'; they shall feed in the ways, and in all high hills shall be their pasture;", "acv": "saying to those who are bound, Go forth; to those who are in darkness, Show yourselves. They shall feed in the ways, and their pasture shall be on all bare heights.", "anderson": "", "haweis": "", "noyes": "To say to the prisoners, Go forth! To them that are in darkness, Come to the light! They shall feed in the ways, And on all high places shall be their pasture.", "webster": "That thou mayest say to the prisoners, Go forth; to them that [are] in darkness, Show yourselves. They shall feed in the ways, and their pastures [shall be] in all high places.", "vulgate": "ut diceres his qui vincti sunt exite et his qui in tenebris revelamini super vias pascentur et in omnibus planis pascua eorum;", "brenton": "saying to them that are in bonds, Go forth; and bidding them that are in darkness shew themselves. They shall be fed in all the ways, and in all the paths shall be their pasture."}}, {"v": 10, "ref": "49:10", "o": "לֹ֤א יִרְעָ֨בוּ֙ וְ/לֹ֣א יִצְמָ֔אוּ וְ/לֹא יַכֵּ֥/ם שָׁרָ֖ב וָ/שָׁ֑מֶשׁ כִּי מְרַחֲמָ֣/ם יְנַהֲגֵ֔/ם וְ/עַל מַבּ֥וּעֵי מַ֖יִם יְנַהֲלֵֽ/ם", "en": {"kjv": "They shall not hunger nor thirst; neither shall the heat nor sun smite them: for he that hath mercy on them shall lead them, even by the springs of water shall he guide them.", "web": "They shall not hunger nor thirst; neither shall the heat nor sun strike them: for he who has mercy on them will lead them, even by springs of water he will guide them.", "bsb": "They will not hunger or thirst, nor will scorching heat or sun beat down on them. For He who has compassion on them will guide them and lead them beside springs of water.", "asv": "They shall not hunger nor thirst; neither shall the heat nor sun smite them: for he that hath mercy on them will lead them, even by springs of water will he guide them.", "ylt": "They do not hunger, nor thirst, Nor smite them doth mirage and sun, For He who is pitying them doth lead them, And by fountains of waters doth tend them.", "dra": "They shall not hunger, nor thirst, neither shall the heat nor the sun strike them: for he that is merciful to them, shall be their shepherd, and at the fountains of waters he shall give them drink.", "bbe": "They will not be in need of food or drink, or be troubled by the heat or the sun: for he who has mercy on them will be their guide, taking them by the springs of water.", "geneva": "They shall not be hungrie, neither shall they be thirstie, neither shall the heat smite them, nor the sunne: for he that hath compassion on them, shall leade them: euen to the springs of waters shall he driue them.", "wycliffe": "Thei schulen not hungre, and thei schulen no more thirste, and heete, and the sunne schal not smyte hem; for the merciful doere of hem schal gouerne hem, and schal yyue drynk to hem at the wellis of watris.", "rotherham": "They shall neither hunger, nor thirst, Nor shall smite them the glowing sand, or the glaring sun,—For, he that hath compassion upon them, will lead them, And unto springs of water, will he conduct them.", "darby": "They shall not hunger nor thirst, neither shall the heat nor sun smite them; for he that hath mercy on them will lead them, and by the springs of water will he guide them.", "twenty": "", "jps": "They shall not hunger nor thirst, neither shall the heat nor sun smite them; for He that hath compassion on them will lead them, even by the springs of water will He guide them.", "acv": "They shall not hunger nor thirst, neither shall the heat nor sun smite them. For he who has mercy on them will lead them. He will guide them even by springs of water.", "anderson": "", "haweis": "", "noyes": "They shall not hunger, neither shall they thirst; Neither shall the heat nor the sun smite them; For he that hath compassion on them shall lead them; To springs of water shall he guide them.", "webster": "They shall not hunger nor thirst, neither shall the heat nor sun smite them: for he that hath mercy on them shall lead them, even by the springs of water shall he guide them.", "vulgate": "non esurient neque sitient et non percutiet eos aestus et sol quia miserator eorum reget eos et ad fontes aquarum portabit eos;", "brenton": "They shall not hunger, neither shall they thirst; neither shall the heat nor the sun smite them; but he that has mercy on them shall comfort them, and by fountains of waters shall he lead them."}}, {"v": 11, "ref": "49:11", "o": "וְ/שַׂמְתִּ֥י כָל הָרַ֖/י לַ/דָּ֑רֶךְ וּ/מְסִלֹּתַ֖/י יְרֻמֽוּ/ן", "en": {"kjv": "And I will make all my mountains a way, and my highways shall be exalted.", "web": "I will make all my mountains a way, and my highways shall be exalted.", "bsb": "I will turn all My mountains into roads, and My highways will be raised up.", "asv": "And I will make all my mountains a way, and my highways shall be exalted.", "ylt": "And I have made all My mountains for a way, And My highways are lifted up.", "dra": "And I will make all my mountains a way, and my paths shall be exalted.", "bbe": "And I will make all my mountains a way, and my highways will be lifted up.", "geneva": "And I will make all my mountaines, as a way, and my paths shalbe exalted.", "wycliffe": "And Y schal sette alle myn hillis in to weie, and my pathis schulen be enhaunsid.", "rotherham": "Then will I make of all my mountains, a road, And my highways, shall be upraised.", "darby": "And I will make all my mountains a way, and my highways shall be raised up.", "twenty": "", "jps": "And I will make all My mountains a way, and My highways shall be raised on high.", "acv": "And I will make all my mountains a way, and my highways shall be exalted.", "anderson": "", "haweis": "", "noyes": "And I will make all my mountains a highway; And my roads shall be prepared.", "webster": "And I will make all my mountains a way, and my highways shall be exalted.", "vulgate": "et ponam omnes montes meos in viam et semitae meae exaltabuntur;", "brenton": "And I will make every mountain a way, and every path a pasture to them."}}, {"v": 12, "ref": "49:12", "o": "הִנֵּה אֵ֕לֶּה מֵ/רָח֖וֹק יָבֹ֑אוּ וְ/הִֽנֵּה אֵ֨לֶּה֙ מִ/צָּפ֣וֹן וּ/מִ/יָּ֔ם וְ/אֵ֖לֶּה מֵ/אֶ֥רֶץ סִינִֽים", "en": {"kjv": "Behold, these shall come from far: and, lo, these from the north and from the west; and these from the land of Sinim.", "web": "Behold, these shall come from far; and behold, these from the north and from the west; and these from the land of Sinim.”", "bsb": "Behold, they will come from far away, from the north and from the west, and from the land of Aswan.”", "asv": "Lo, these shall come from far; and, lo, these from the north and from the west; and these from the land of Sinim.", "ylt": "Lo, these from afar come in, And lo, these from the north, and from the sea, And these from the land of Sinim.", "dra": "Behold these shall come from afar, and behold these from the north and from the sea, and these from the south country.", "bbe": "See, these are coming from far; and these from the north and the west; and these from the land of Sinim.", "geneva": "Beholde, these shall come from farre: and loe, these from the North and from the West, and these from the land of Sinim.", "wycliffe": "Lo! these men schulen come fro fer, and lo! thei schulen come fro the north, and see, and these fro the south lond.", "rotherham": "Lo! these, from afar, shall come in,—And lo! these, from the North and from the West, And these, from the land of Sinim.", "darby": "Behold, these shall come from afar; and behold, these from the north and from the west; and these from the land of Sinim.", "twenty": "", "jps": "Behold, these shall come from far; and, lo, these from the north and from the west, and these from the land of Sinim.", "acv": "Lo, these shall come from far, and, lo, these from the north and from the west, and these from the land of Sinim.", "anderson": "", "haweis": "", "noyes": "Behold! these shall come from far; And behold! these from the North and from the West, And these from the land of Sinim.", "webster": "Behold, these shall come from far: and lo, these from the north and from the west; and these from the land of Sinim.", "vulgate": "ecce isti de longe venient et ecce illi ab aquilone et mari et isti de terra australi;", "brenton": "Behold, these shall come from far: and these from the north and the west, and others from the land of the Persians."}}, {"v": 13, "ref": "49:13", "o": "רָנּ֤וּ שָׁמַ֨יִם֙ וְ/גִ֣ילִי אָ֔רֶץ יפצחו וּ/פִצְח֥וּ הָרִ֖ים רִנָּ֑ה כִּֽי נִחַ֤ם יְהוָה֙ עַמּ֔/וֹ וַ/עֲנִיָּ֖/ו יְרַחֵֽם", "en": {"kjv": "Sing, O heavens; and be joyful, O earth; and break forth into singing, O mountains: for the Lord hath comforted his people, and will have mercy upon his afflicted.", "web": "Sing, heavens; and be joyful, earth; and break out into singing, mountains: for Yahweh has comforted his people, and will have compassion on his afflicted.", "bsb": "Shout for joy, O heavens; rejoice, O earth; break forth in song, O mountains! For the LORD has comforted His people, and He will have compassion on His afflicted ones.", "asv": "Sing, O heavens; and be joyful, O earth; and break forth into singing, O mountains: for Jehovah hath comforted his people, and will have compassion upon his afflicted.", "ylt": "Sing, O heavens, and joy, O earth, And break forth, O mountains, with singing, For comforted hath Jehovah His people, And His afflicted ones He doth pity.", "dra": "Give praise, O ye heavens, and rejoice, O earth, ye mountains, give praise with jubilation: because the Lord hath comforted his people, and will have mercy on his poor ones.", "bbe": "Let your voice be loud in song, O heavens; and be glad, O earth; make sounds of joy, O mountains, for the Lord has given comfort to his people, and will have mercy on his crushed ones.", "geneva": "Reioyce, O heauens: and bee ioyfull, O earth: brast foorth into praise, O mountaines: for God hath comforted his people, and will haue mercie vpon his afflicted.", "wycliffe": "Heuenes, herie ye, and, thou erthe, make ful out ioie; hillis, synge ye hertli heriyng; for the Lord coumfortide his puple, and schal haue merci on hise pore men.", "rotherham": "Shout in triumph—O heavens! And exult—O earth! And break forth, ye mountains, into shouts of triumph,—For Yahweh hath comforted his people, And on his humbled ones, taketh he compassion.", "darby": "Shout, ye heavens; and be joyful, thou earth; and break forth into singing, ye mountains: for Jehovah hath comforted his people, and will have mercy upon his afflicted ones.", "twenty": "", "jps": "Sing, O heavens, and be joyful, O earth, and break forth into singing, O mountains; for HaShem hath comforted His people, and hath compassion upon His afflicted.", "acv": "Sing, O heavens, and be joyful, O earth, and break forth into singing, O mountains. For Jehovah has comforted his people, and will have compassion upon his afflicted.", "anderson": "", "haweis": "", "noyes": "Sing, O ye heavens, and rejoice, O earth! Break forth into singing, ye mountains! For Jehovah comforteth his people, And hath compassion on his afflicted ones.", "webster": "Sing, O heavens, and be joyful, O earth; and break forth into singing, O mountains: for the LORD hath comforted his people, and will have mercy upon his afflicted.", "vulgate": "laudate caeli et exulta terra iubilate montes laudem quia consolatus est Dominus populum suum et pauperum suorum miserebitur;", "brenton": "Rejoice, ye heavens; and let the earth be glad: let the mountains break forth with joy; for the Lard has had mercy on his people, and has comforted the lowly ones of his people."}}, {"v": 14, "ref": "49:14", "o": "וַ/תֹּ֥אמֶר צִיּ֖וֹן עֲזָבַ֣/נִי יְהוָ֑ה וַ/אדֹנָ֖/י שְׁכֵחָֽ/נִי", "en": {"kjv": "But Zion said, The Lord hath forsaken me, and my Lord hath forgotten me.", "web": "But Zion said, “Yahweh has forsaken me, and the Lord has forgotten me.”", "bsb": "But Zion said, “The LORD has forsaken me; the Lord has forgotten me!”", "asv": "But Zion said, Jehovah hath forsaken me, and the Lord hath forgotten me.", "ylt": "And Zion saith, `Jehovah hath forsaken me, And my Lord hath forgotten me.'", "dra": "And Sion said: The Lord hath forsaken me, and the Lord hath forgotten me.", "bbe": "But Zion said, The Lord has given me up, I have gone from his memory.", "geneva": "But Zion saide, The Lord hath forsaken me, and my Lord hath forgotten me.", "wycliffe": "And Syon seide, The Lord hath forsake me, and the Lord hath foryete me.", "rotherham": "But Zion had said. Yahweh hath forsaken me,—Even, My Lord, hath forgotten me!", "darby": "But Zion said, Jehovah hath forsaken me, and the Lord hath forgotten me.", "twenty": "", "jps": "But Zion said: 'The HaShem hath forsaken me, and the L-rd hath forgotten me.'", "acv": "But Zion said, Jehovah has forsaken me, and the Lord has forgotten me.", "anderson": "", "haweis": "", "noyes": "Zion saith, \"Jehovah hath forsaken me; The Lord hath forgotten me.\"", "webster": "But Zion said, The LORD hath forsaken me, and my Lord hath forgotten me.", "vulgate": "et dixit Sion dereliquit me Dominus et Dominus oblitus est mei;", "brenton": "But Sion said, The Lord has forsaken me, and, The Lord has forgotten me."}}, {"v": 15, "ref": "49:15", "o": "הֲ/תִשְׁכַּ֤ח אִשָּׁה֙ עוּלָ֔/הּ מֵ/רַחֵ֖ם בֶּן בִּטְנָ֑/הּ גַּם אֵ֣לֶּה תִשְׁכַּ֔חְנָה וְ/אָנֹכִ֖י לֹ֥א אֶשְׁכָּחֵֽ/ךְ", "en": {"kjv": "Can a woman forget her sucking child, that she should not have compassion on the son of her womb? yea, they may forget, yet will I not forget thee.", "web": "“Can a woman forget her nursing child, that she should not have compassion on the son of her womb? Yes, these may forget, yet I will not forget you!", "bsb": "“Can a woman forget her nursing child, or lack compassion for the son of her womb? Even if she could forget, I will not forget you!", "asv": "Can a woman forget her sucking child, that she should not have compassion on the son of her womb? yea, these may forget, yet will not I forget thee.", "ylt": "Forget doth a woman her suckling, The loved one--the son of her womb? Yea, these forget--but I--I forget not thee.", "dra": "Can a woman forget her infant, so as not to have pity on the son of her womb? and if she should forget, yet will not I forget thee.", "bbe": "Will a woman give up the child at her breast, will she be without pity for the fruit of her body? yes, these may, but I will not let you go out of my memory.", "geneva": "Can a woman forget her childe, and not haue compassion on the sonne of her wombe? though they should forget, yet wil I not forget thee.", "wycliffe": "Whether a womman may foryete hir yonge child, that sche haue not merci on the sone of hir wombe? thouy sche foryetith, netheles Y schal not foryete thee.", "rotherham": "Can, a woman, forget, her sucking child, Past taking compassion on the son of her womb? Even these, may forget, Yet will, I, not forget, thee:", "darby": "Can a woman forget her sucking child, that she should not have compassion on the son of her womb? Even these forget, but I will not forget thee.", "twenty": "", "jps": "Can a woman forget her sucking child, that she should not have compassion on the son of her womb? Yea, these may forget, yet will not I forget thee.", "acv": "Can a woman forget her sucking child, that she should not have compassion on the son of her womb? Yea, these may forget, yet I will not forget thee.", "anderson": "", "haweis": "", "noyes": "Can a woman forget her sucking child, So as not to have compassion on the son of her womb? Yet, should they forget, I will never forget thee!", "webster": "Can a woman forget her sucking child, that she should not have compassion on the son of her womb? yes, they may forget, yet I will not forget thee.", "vulgate": "numquid oblivisci potest mulier infantem suum ut non misereatur filio uteri sui et si illa oblita fuerit ego tamen non obliviscar tui;", "brenton": "Will a woman forget her child, so as not to have compassion upon the offspring of her womb? but if a woman should even forget these, yet I will not forget thee, saith the Lord."}}, {"v": 16, "ref": "49:16", "o": "הֵ֥ן עַל כַּפַּ֖יִם חַקֹּתִ֑י/ךְ חוֹמֹתַ֥יִ/ךְ נֶגְדִּ֖/י תָּמִֽיד", "en": {"kjv": "Behold, I have graven thee upon the palms of my hands; thy walls are continually before me.", "web": "Behold, I have engraved you on the palms of my hands; your walls are continually before me.", "bsb": "Behold, I have inscribed you on the palms of My hands; your walls are ever before Me.", "asv": "Behold, I have graven thee upon the palms of my hands; thy walls are continually before me.", "ylt": "Lo, on the palms of the hand I have graven thee, Thy walls are before Me continually.", "dra": "Behold, I have graven thee in my hands: thy walls are always before my eyes.", "bbe": "See, your name is marked on my hands; your walls are ever before me.", "geneva": "Behold, I haue grauen thee vpon the palme of mine hands: thy walles are euer in my sight.", "wycliffe": "Lo! Y haue write thee in myn hondis; thi wallis ben euer bifore myn iyen.", "rotherham": "Lo! on the palms of my hands, have I portrayed thee,—Thy walls are before me continually.", "darby": "Lo, I have graven thee upon the palms of [my] hands; thy walls are continually before me.", "twenty": "", "jps": "Behold, I have graven thee upon the palms of My hands; thy walls are continually before Me.", "acv": "Behold, I have engraved thee upon the palms of my hands. Thy walls are continually before me.", "anderson": "", "haweis": "", "noyes": "Behold, I have graven thee on the palms of my hands; Thy walls are ever before my eyes.", "webster": "Behold, I have graven thee upon the palms of [my] hands; thy walls [are] continually before me.", "vulgate": "ecce in manibus meis descripsi te muri tui coram oculis meis semper;", "brenton": "Behold, I have painted thy walls on my hands, and thou art continually before me."}}, {"v": 17, "ref": "49:17", "o": "מִֽהֲר֖וּ בָּנָ֑יִ/ךְ מְהָֽרְסַ֥יִ/ךְ וּ/מַחֲרִבַ֖יִ/ךְ מִמֵּ֥/ךְ יֵצֵֽאוּ", "en": {"kjv": "Thy children shall make haste; thy destroyers and they that made thee waste shall go forth of thee.", "web": "Your children make haste; your destroyers and those who made you waste shall go out from you.", "bsb": "Your builders hasten back; your destroyers and wreckers depart from you.", "asv": "Thy children make haste; thy destroyers and they that made thee waste shall go forth from thee.", "ylt": "Hastened have those building thee, Those destroying thee, and laying thee waste, go out from thee.", "dra": "Thy builders are come: they that destroy thee and make thee waste shall go out of thee.", "bbe": "Your builders are coming quickly; your haters and those who made you waste will go out of you.", "geneva": "Thy builders make haste: thy destroiers and they that made thee waste, are departed from thee.", "wycliffe": "The bilderis ben comun; thei that distrien thee, and scateren, schulen go awei fro thee.", "rotherham": "In haste are thy sons,—They who have been tearing thee down and laying thee waste, out of thee, let them go forth!", "darby": "Thy sons shall make haste; thy destroyers and they that laid thee waste shall go forth from thee.", "twenty": "", "jps": "Thy children make haste; thy destroyers and they that made thee waste shall go forth from thee.", "acv": "Thy sons make haste. Thy destroyers and those who made thee waste shall go forth from thee.", "anderson": "", "haweis": "", "noyes": "Thy children shall make haste; They that destroyed and laid thee waste shall depart from thee.", "webster": "Thy children shall make haste; thy destroyers and they that made thee waste, shall go forth from thee.", "vulgate": "venerunt structores tui destruentes te et dissipantes a te exibunt;", "brenton": "And thou shalt soon be built by those by whom thou were destroyed, and they that made thee desolate shall go forth of thee."}}, {"v": 18, "ref": "49:18", "o": "שְׂאִֽי סָבִ֤יב עֵינַ֨יִ/ךְ֙ וּ/רְאִ֔י כֻּלָּ֖/ם נִקְבְּצ֣וּ בָֽאוּ לָ֑/ךְ חַי אָ֣נִי נְאֻם יְהוָ֗ה כִּ֤י כֻלָּ/ם֙ כָּ/עֲדִ֣י תִלְבָּ֔שִׁי וּֽ/תְקַשְּׁרִ֖י/ם כַּ/כַּלָּֽה", "en": {"kjv": "Lift up thine eyes round about, and behold: all these gather themselves together, and come to thee. As I live, saith the Lord, thou shalt surely clothe thee with them all, as with an ornament, and bind them on thee, as a bride doeth.", "web": "Lift up your eyes all around, and see: all these gather themselves together, and come to you. As I live,” says Yahweh, “you shall surely clothe yourself with them all as with an ornament, and dress yourself with them, like a bride.", "bsb": "Lift up your eyes and look around. They all gather together; they come to you. As surely as I live,” declares the LORD, “you will wear them all as jewelry and put them on like a bride.", "asv": "Lift up thine eyes round about, and behold: all these gather themselves together, and come to thee. As I live, saith Jehovah, thou shalt surely clothe thee with them all as with an ornament, and gird thyself with them, like a bride.", "ylt": "Lift up round about thine eyes and see, All of them have been gathered, They have come to thee. I live, an affirmation of Jehovah! Surely all of them as an ornament thou puttest on, And thou bindest them on like a bride.", "dra": "Lift up thy eyes round about, and see all these are gathered together, they are come to thee: I live, saith the Lord, thou shalt be clothed with all these as with an ornament, and as a bride thou shalt put them about thee.", "bbe": "Let your eyes be lifted up round about, and see: they are all coming together to you. By my life, says the Lord, truly you will put them all on you as an ornament, and be clothed with them like a bride.", "geneva": "Lift vp thine eies round about and behold: all these gather themselues together and come to thee: as I liue, sayeth the Lord, thou shalt surely put them all vpon thee as a garment, and girde thy selfe with them like a bride.", "wycliffe": "Reise thin iyen in cumpas, and se; alle these men ben gaderid togidere, thei ben comun to thee. Y lyue, seith the Lord, for thou schalt be clothid with alle these as with an ournement, and thou as a spousesse schalt bynde hem to thee.", "rotherham": "Lift up, round about, thine eyes and see, All those, have gathered themselves together—have come to thee! As I live, Declareth Yahweh,—Surely all those as an ornament, shalt thou put on, And bind them about thee for a girdle as a bride.", "darby": "Lift up thine eyes round about and behold: they all gather themselves together, they come to thee. As I live, saith Jehovah, thou shalt indeed clothe thee with them all as with an ornament, and bind them on as a bride doth.", "twenty": "", "jps": "Lift up thine eyes round about, and behold: all these gather themselves together, and come to thee. As I live, saith HaShem, thou shalt surely clothe thee with them all as with an ornament, and gird thyself with them, like a bride.", "acv": "Lift up thine eyes round about, and behold. All these gather themselves together, and come to thee. As I live, says Jehovah, thou shall surely clothe thee with them all, as with an ornament, and gird thyself with them, like a bride.", "anderson": "", "haweis": "", "noyes": "Lift up thine eyes around, and see! They all assemble themselves, and come to thee. As I live, saith Jehovah, Thou shalt surely clothe thee with them all, as with a rich dress; Thou shalt bind them on thee, as a bride her jewels.", "webster": "Lift up thy eyes around, and behold: all these assemble themselves, [and] come to thee. [As] I live, saith the LORD, thou shalt surely clothe thee with them all, as with an ornament, and bind them [on thee], as a bride [doeth].", "vulgate": "leva in circuitu oculos tuos et vide omnes isti congregati sunt venerunt tibi vivo ego dicit Dominus quia omnibus his velut ornamento vestieris et circumdabis tibi eos quasi sponsa;", "brenton": "Lift up thine eyes round about, and look on them all; behold, they are gathered together, and are come to thee. As I live, saith the Lord, thou shalt clothe thyself with them all as with an ornament, and put them on as a bride her attire."}}, {"v": 19, "ref": "49:19", "o": "כִּ֤י חָרְבֹתַ֨יִ/ךְ֙ וְ/שֹׁ֣מְמֹתַ֔יִ/ךְ וְ/אֶ֖רֶץ הֲרִֽסֻתֵ֑י/ךְ כִּ֤י עַתָּה֙ תֵּצְרִ֣י מִ/יּוֹשֵׁ֔ב וְ/רָחֲק֖וּ מְבַלְּעָֽיִ/ךְ", "en": {"kjv": "For thy waste and thy desolate places, and the land of thy destruction, shall even now be too narrow by reason of the inhabitants, and they that swallowed thee up shall be far away.", "web": "“For, as for your waste and your desolate places, and your land that has been destroyed, surely now you shall be too small for the inhabitants, and those who swallowed you up shall be far away.", "bsb": "For your ruined and desolate places and your ravaged land will now indeed be too small for your people, and those who devoured you will be far away.", "asv": "For, as for thy waste and thy desolate places, and thy land that hath been destroyed, surely now shalt thou be too strait for the inhabitants, and they that swallowed thee up shall be far away.", "ylt": "Because thy wastes, and thy desolate places, And the land of thy ruins, Surely now are straitened because of inhabitants, And far off have been those consuming thee.", "dra": "For thy deserts, and thy desolate places, and the land of thy destruction shall now be too narrow by reason of the inhabitants, and they that swallowed thee up shall be chased far away.", "bbe": "For though the waste places of your land have been given to destruction, now you will not be wide enough for your people, and those who made you waste will be far away.", "geneva": "For thy desolations, and thy waste places, and thy land destroied, shall surely be now narow for them that shall dwell in it, and they that did deuoure thee, shalbe farre away.", "wycliffe": "For whi thi desertis, and thi wildirnessis, and the lond of thi fallyng now schulen be streit for enhabiteris; and thei schulen be dryuun awei fer, that swolewiden thee.", "rotherham": "Surely, as for thy wastes, and thy desolations, and thy land of ruins, Surely, now, shalt thou be too strait for thine inhabitants, And, far off, shall be they who have been swallowing thee up.", "darby": "For [in] thy waste and thy desolate places, and thy destroyed land, thou shalt even now be too straitened by reason of the inhabitants, and they that swallowed thee up shall be far away.", "twenty": "", "jps": "For thy waste and thy desolate places and thy land that hath been destroyed--surely now shalt thou be too strait for the inhabitants, and they that swallowed thee up shall be far away.", "acv": "For, as for thy waste and thy desolate places, and thy land that has been destroyed, surely now thou shall be too narrow for the inhabitants, and those who swallowed thee up shall be far away.", "anderson": "", "haweis": "", "noyes": "For thy waste and desolate places, and thy land laid in ruins, Shall now be too narrow for the inhabitants; And they that devoured thee shall be far away.", "webster": "For thy waste and thy desolate places, and the land of thy destruction, shall even now be too narrow by reason of the inhabitants, and they that swallowed thee up shall be far away.", "vulgate": "quia deserta tua et solitudines tuae et terra ruinae tuae nunc angusta erunt prae habitatoribus et longe fugabuntur qui absorbebant te;", "brenton": "For thy desert and marred and ruined places shall now be too narrow by reason of the inhabitants, and they that devoured thee shall be removed far from thee."}}, {"v": 20, "ref": "49:20", "o": "ע֚וֹד יֹאמְר֣וּ בְ/אָזְנַ֔יִ/ךְ בְּנֵ֖י שִׁכֻּלָ֑יִ/ךְ צַר לִ֥/י הַ/מָּק֖וֹם גְּשָׁ/ה לִּ֥/י וְ/אֵשֵֽׁבָה", "en": {"kjv": "The children which thou shalt have, after thou hast lost the other, shall say again in thine ears, The place is too strait for me: give place to me that I may dwell.", "web": "The children of your bereavement shall yet say in your ears, The place is too small for me; give place to me that I may dwell.", "bsb": "Yet the children of your bereavement will say in your hearing, ‘This place is too small for us; make room for us to live here.’", "asv": "The children of thy bereavement shall yet say in thine ears, The place is too strait for me; give place to me that I may dwell.", "ylt": "Again do the sons of thy bereavement say in thine ears: `The place is too strait for me, Come nigh to me--and I dwell.'", "dra": "The children of thy barrenness shall still say in thy ears: The place is too strait for me, make me room to dwell in.", "bbe": "The children to whom you gave birth in other lands will say in your ears, The place is not wide enough for me: make room for me to have a resting-place.", "geneva": "The children of thy barennesse shall say againe in thine eares, The place is straict for mee: giue place to me that I may dwell.", "wycliffe": "Yit the sones of thi bareynesse schulen seie in thin eeris, The place is streit to me, make thou a space to me for to dwelle.", "rotherham": "The children of whom thou wast bereaved shall yet say in thine ears,—Too strait for me, is the place Make room for me that I may settle down.", "darby": "The children of thy bereavement shall yet say in thine ears, The place is too narrow for me: make room for me, that I may dwell.", "twenty": "", "jps": "The children of thy bereavement shall yet say in thine ears: 'The place is too strait for me; give place to me that I may dwell.'", "acv": "The sons of thy bereavement shall yet say in thine ears, The place is too narrow for me. Give a place to me that I may dwell.", "anderson": "", "haweis": "", "noyes": "Thou, that hast been childless, shalt yet hear thy sons exclaim: \"The place is too narrow for me; make room for me that I may dwell.\"", "webster": "The children which thou shalt have, after thou hast lost the other, shall say again in thy ears, The place [is] too narrow for me: give place to me that I may dwell.", "vulgate": "adhuc dicent in auribus tuis filii sterilitatis tuae angustus mihi est locus fac spatium mihi ut habitem;", "brenton": "For thy sons whom thou hast lost shall say in thine ears, The place is too narrow for me: make room for me that I may dwell."}}, {"v": 21, "ref": "49:21", "o": "וְ/אָמַ֣רְתְּ בִּ/לְבָבֵ֗/ךְ מִ֤י יָֽלַד לִ/י֙ אֶת אֵ֔לֶּה וַ/אֲנִ֥י שְׁכוּלָ֖ה וְ/גַלְמוּדָ֑ה גֹּלָ֣ה וְ/סוּרָ֗ה וְ/אֵ֨לֶּה֙ מִ֣י גִדֵּ֔ל הֵ֤ן אֲנִי֙ נִשְׁאַ֣רְתִּי לְ/בַדִּ֔/י אֵ֖לֶּה אֵיפֹ֥ה הֵֽם", "en": {"kjv": "Then shalt thou say in thine heart, Who hath begotten me these, seeing I have lost my children, and am desolate, a captive, and removing to and fro? and who hath brought up these? Behold, I was left alone; these, where had they been?", "web": "Then you will say in your heart, ‘Who has conceived these for me, since I have been bereaved of my children, and am solitary, an exile, and wandering back and forth? Who has brought up these? Behold, I was left alone; these, where were they?’”", "bsb": "Then you will say in your heart, ‘Who has begotten these for me? I was bereaved and barren; I was exiled and rejected. So who has reared them? Look, I was left all alone, so where did they come from?’”", "asv": "Then shalt thou say in thy heart, Who hath begotten me these, seeing I have been bereaved of my children, and am solitary, an exile, and wandering to and fro? and who hath brought up these? Behold, I was left alone; these, where were they?", "ylt": "And thou hast said in thy heart: `Who hath begotten for me--these? And I bereaved and gloomy, A captive, and turned aside, And these--who hath nourished? Lo, I--I was left by myself, these--whence are they?", "dra": "And thou shalt say in thy heart: Who hath begotten these? I was barren and brought not forth, led away, and captive: and who hath brought up these? I was destitute and alone: and these, where were they?", "bbe": "Then you will say in your heart, Who has given me all these children? when my children had been taken from me, and I was no longer able to have others, who took care of these? when I was by myself, where then were these?", "geneva": "Then shalt thou say in thine heart, Who hath begotten mee these, seeing I am baren and desolate, a captiue and a wanderer to and from? and who hath nourished them? beholde, I was left alone: whence are these?", "wycliffe": "And thou schalt seie in thin herte, Who gendride these sones to me? Y am bareyn, not berynge child; Y am led ouer, and prisoner; and who nurschide these sones? Y am destitute, and aloone; and where weren these?", "rotherham": "Then shalt thou say in thy heart,—Who hath borne me, these, Seeing, I, have been bereaved and unfruitful, a captive and banished? These, therefore, who hath brought them up? Lo! I, was left, alone, These, where were they?", "darby": "And thou shalt say in thy heart, Who hath borne me these, seeing I had lost my children and was desolate, an exile, and driven about? and who hath brought up these? behold, I was left alone; these, where were they?", "twenty": "", "jps": "Then shalt thou say in thy heart: 'Who hath begotten me these, seeing I have been bereaved of my children, and am solitary, an exile, and wandering to and fro? And who hath brought up these? Behold, I was left alone; these, where were they?'", "acv": "Then thou shall say in thy heart, Who has begotten these for me, seeing I have been bereaved of my sons, and am solitary, an exile, and wandering to and fro? And who has brought up these? Behold, I was left alone, these, where were they?", "anderson": "", "haweis": "", "noyes": "And thou shalt say in thy heart, Who hath begotten me these? I surely was childless and unfruitful, An exile, and an outcast; who then hath brought up these? Behold, I was left alone; these, then, where were they?", "webster": "Then shalt thou say in thy heart, Who hath begotten these for me, seeing I have lost my children, and am desolate, a captive, and removing to and fro? and who hath brought up these? Behold, I was left alone; these, where [have] they [been]?", "vulgate": "et dices in corde tuo quis genuit mihi istos ego sterilis et non pariens transmigrata et captiva et istos quis enutrivit ego destituta et sola et isti ubi hic erant;", "brenton": "And thou shalt say in thine heart, Who has begotten me these? whereas I was childless, and a widow; but who has brought up these for me? and I was left alone; but whence came these to me?"}}, {"v": 22, "ref": "49:22", "o": "כֹּֽה אָמַ֞ר אֲדֹנָ֣/י יְהוִ֗ה הִנֵּ֨ה אֶשָּׂ֤א אֶל גּוֹיִם֙ יָדִ֔/י וְ/אֶל עַמִּ֖ים אָרִ֣ים נִסִּ֑/י וְ/הֵבִ֤יאוּ בָנַ֨יִ/ךְ֙ בְּ/חֹ֔צֶן וּ/בְנֹתַ֖יִ/ךְ עַל כָּתֵ֥ף תִּנָּשֶֽׂאנָה", "en": {"kjv": "Thus saith the Lord God, Behold, I will lift up mine hand to the Gentiles, and set up my standard to the people: and they shall bring thy sons in their arms, and thy daughters shall be carried upon their shoulders.", "web": "Thus says the Lord Yahweh, “Behold, I will lift up my hand to the nations, and set up my banner to the peoples; and they shall bring your sons in their bosom, and your daughters shall be carried on their shoulders.", "bsb": "This is what the Lord GOD says: “Behold, I will lift up My hand to the nations, and raise My banner to the peoples. They will bring your sons in their arms and carry your daughters on their shoulders.", "asv": "Thus saith the Lord Jehovah, Behold, I will lift up my hand to the nations, and set up my ensign to the peoples; and they shall bring thy sons in their bosom, and thy daughters shall be carried upon their shoulders.", "ylt": "Thus said the Lord Jehovah: `Lo, I lift up unto nations My hand, And unto peoples I raise up Mine ensign, And they have brought thy sons in the bosom, And thy daughters on the shoulder are carried.", "dra": "Thus saith the Lord God: Behold I will lift up my hand to the Gentiles, and will set up my standard to the people. And they shall bring thy sons in their arms, and carry thy daughters upon their shoulders.", "bbe": "This is the word of the Lord God: See, I will make a sign with my hand to the nations, and put up my flag for the peoples; and they will take up your sons on their beasts, and your daughters on their backs.", "geneva": "Thus sayeth the Lord God, Beholde, I will lift vp mine hande to the Gentiles and set vp my stadart to the people, and they shall bring thy sonnes in their armes: and thy daughters shall be caried vpon their shoulders.", "wycliffe": "The Lord God seith these thingis, Lo! Y reise myn hond to hethene men, and Y schal enhaunce my signe to puplis; and thei schulen brynge thi sones in armes, and thei schulen bere thi douytris on shuldris.", "rotherham": "Thus, saith My Lord, Yahweh—Lo! I will lift up, unto nations my hand, Yea unto peoples, will I raise high my banner,—And they shall bring in thy sons in their bosom, And, thy daughters, on the shoulder shall be borne;", "darby": "Thus saith the Lord Jehovah: Behold, I will lift up my hand to the nations, and set up my banner to the peoples; and they shall bring thy sons in [their] bosom, and thy daughters shall be carried upon the shoulder.", "twenty": "", "jps": "Thus saith the L-rd GOD: Behold, I will lift up My hand to the nations, and set up Mine ensign to the peoples, and they shall bring thy sons in their bosom, and thy daughters shall be carried upon their shoulders.", "acv": "Thus says the lord Jehovah: Behold, I will lift up my hand to the nations, and set up my ensign to the peoples. And they shall bring thy sons in their bosom, and thy daughters shall be carried upon their shoulders.", "anderson": "", "haweis": "", "noyes": "Thus saith the Lord Jehovah: I will lift up my hand to the nations, And set up my standard to the kingdoms; They shall bring thy sons in their arms, And thy daughters upon their shoulders.", "webster": "Thus saith the Lord GOD, Behold, I will lift up my hand to the Gentiles, and set up my standard to the people: and they shall bring thy sons in [their] arms, and thy daughters shall be carried upon [their] shoulders.", "vulgate": "haec dicit Dominus Deus ecce levo ad gentes manum meam et ad populos exaltabo signum meum et adferent filios tuos in ulnis et filias tuas super umeros portabunt;", "brenton": "Thus saith the Lord, even the Lord, Behold, I lift up mine hand to the nations, and I will lift up my signal to the islands: and they shall bring thy sons in their bosom, and shall bear thy daughters on their shoulders."}}, {"v": 23, "ref": "49:23", "o": "וְ/הָי֨וּ מְלָכִ֜ים אֹֽמְנַ֗יִ/ךְ וְ/שָׂרֽוֹתֵי/הֶם֙ מֵינִ֣יקֹתַ֔יִ/ךְ אַפַּ֗יִם אֶ֚רֶץ יִשְׁתַּ֣חֲווּ לָ֔/ךְ וַ/עֲפַ֥ר רַגְלַ֖יִ/ךְ יְלַחֵ֑כוּ וְ/יָדַ֨עַתְּ֙ כִּֽי אֲנִ֣י יְהוָ֔ה אֲשֶׁ֥ר לֹֽא יֵבֹ֖שׁוּ קוָֹֽ/י", "en": {"kjv": "And kings shall be thy nursing fathers, and their queens thy nursing mothers: they shall bow down to thee with their face toward the earth, and lick up the dust of thy feet; and thou shalt know that I am the Lord: for they shall not be ashamed that wait for me.", "web": "Kings shall be your nursing fathers, and their queens your nursing mothers: they shall bow down to you with their faces to the earth, and lick the dust of your feet; and you shall know that I am Yahweh; and those who wait for me shall not be disappointed.”", "bsb": "Kings will be your foster fathers, and their queens your nursing mothers. They will bow to you facedown and lick the dust at your feet. Then you will know that I am the LORD; those who hope in Me will never be put to shame.”", "asv": "And kings shall be thy nursing fathers, and their queens thy nursing mothers: they shall bow down to thee with their faces to the earth, and lick the dust of thy feet; and thou shalt know that I am Jehovah; and they that wait for me shall not be put to shame.", "ylt": "And kings have been thy nursing fathers, And their princesses thy nursing mothers; Face to the earth--they bow down to thee, And the dust of thy feet they lick up, And thou hast known that I am Jehovah, That those expecting Me are not ashamed.", "dra": "And kings shall be thy nursing fathers, and queens thy nurses: they shall worship thee with their face toward the earth, and they shall lick up the dust of thy feet. And thou shalt know that I am the Lord, for they shall not be confounded that wait for him.", "bbe": "And kings will take care of you, and queens will give you their milk: they will go down on their faces before you, kissing the dust of your feet; and you will be certain that I am the Lord, and that those who put their hope in me will not be shamed.", "geneva": "And Kings shalbe thy nourcing fathers, and Queenes shalbe thy nources: they shall worship thee with their faces towarde the earth, and licke vp the dust of thy feete: and thou shalt knowe that I am the Lord: for they shall not be ashamed that waite for me.", "wycliffe": "And kingis shulen be thi nurseris, and quenys shulen be thi nursis; with cheer cast doun in to erthe thei schulen worschipe thee, and thei schulen licke the dust of thi feet; and thou schalt wite, that Y am the Lord, on whom thei schulen not be schent, that abiden hym.", "rotherham": "And, kings, shall be, thy foster-fathers. And their queens, thy nursing mothers, With face to the ground, shall they bow down to thee, The dust of thy feet, shall they lick,—So shalt thou know that, I, am Yahweh, In that, they shall not be put to shame, Who were waiting for me.", "darby": "And kings shall be thy nursing-fathers, and their princesses thy nursing-mothers: they shall bow down to thee with the face toward the earth, and lick up the dust of thy feet. And thou shalt know that I [am] Jehovah; for they shall not be ashamed who wait on me.", "twenty": "", "jps": "And kings shall be thy foster-fathers, and their queens thy nursing mothers; they shall bow down to thee with their face to the earth, and lick the dust of thy feet; and thou shalt know that I am HaShem, for they shall not be ashamed that wait for Me.", "acv": "And kings shall be thy nursing fathers, and their queens thy nursing mothers. They shall bow down to thee with their faces to the earth, and lick the dust of thy feet. And thou shall know that I am Jehovah, and those who wait for me shall not be put to shame.", "anderson": "", "haweis": "", "noyes": "And kings shall be thy nursing fathers, And queens thy nursing mothers; Upon their faces shall they bow down before thee, And lick the dust of thy feet. Thus shalt thou know that I am Jehovah; And they who trust in me shall not be put to shame.", "webster": "And kings shall be thy nursing fathers, and their queens thy nursing mothers: they shall bow to thee with [their] face towards the earth, and lick up the dust of thy feet; and thou shalt know that I [am] the LORD: for they shall not be ashamed that wait for me.", "vulgate": "et erunt reges nutricii tui et reginae nutrices tuae vultu in terra dimisso adorabunt te et pulverem pedum tuorum lingent et scies quia ego Dominus super quo non confundentur qui expectant eum;", "brenton": "And kings shall be thy nursing fathers, and their princesses thy nurses, they shall bow down to thee on the face of the earth, and shall lick the dust of thy feet; and thou shalt know that I am the Lord, and they that wait on me shall not be ashamed."}}, {"v": 24, "ref": "49:24", "o": "הֲ/יֻקַּ֥ח מִ/גִּבּ֖וֹר מַלְק֑וֹחַ וְ/אִם שְׁבִ֥י צַדִּ֖יק יִמָּלֵֽט", "en": {"kjv": "Shall the prey be taken from the mighty, or the lawful captive delivered?", "web": "Shall the plunder be taken from the mighty, or the lawful captives be delivered?", "bsb": "Can the plunder be snatched from the mighty, or the captives of a tyrant be delivered?", "asv": "Shall the prey be taken from the mighty, or the lawful captives be delivered?", "ylt": "Is prey taken from the mighty? And the captive of the righteous delivered?", "dra": "Shall the prey be taken from the strong? or can that which was taken by the mighty, be delivered?", "bbe": "Will the goods of war be taken from the strong man, or the prisoners of the cruel one be let go?", "geneva": "Shall the pray be taken from the mightie? or the iust captiuitie deliuered?", "wycliffe": "Whether prey schal be takun awei fro a strong man? ether that that is takun of a stalworthe man, mai be saaf?", "rotherham": "Shall prey, be taken from a mighty one? Or the captive of one in the right, be delivered?", "darby": "Shall the prey be taken from the mighty? and shall he that is rightfully captive be delivered?", "twenty": "", "jps": "Shall the prey be taken from the mighty, or the captives of the victorious be delivered?", "acv": "Shall the prey be taken from the mighty, or the lawful captives be delivered?", "anderson": "", "haweis": "", "noyes": "Shall the prey be taken away from the mighty? Or shall the spoil of the terrible be rescued?", "webster": "Shall the prey be taken from the mighty, or the lawful captive delivered?", "vulgate": "numquid tolletur a forte praeda aut quod captum fuerit a robusto salvum esse poterit;", "brenton": "Will any one take spoils from a giant? and if one should take a man captive unjustly, shall he be delivered?"}}, {"v": 25, "ref": "49:25", "o": "כִּי כֹ֣ה אָמַ֣ר יְהוָ֗ה גַּם שְׁבִ֤י גִבּוֹר֙ יֻקָּ֔ח וּ/מַלְק֥וֹחַ עָרִ֖יץ יִמָּלֵ֑ט וְ/אֶת יְרִיבֵ/ךְ֙ אָנֹכִ֣י אָרִ֔יב וְ/אֶת בָּנַ֖יִ/ךְ אָנֹכִ֥י אוֹשִֽׁיעַ", "en": {"kjv": "But thus saith the Lord, Even the captives of the mighty shall be taken away, and the prey of the terrible shall be delivered: for I will contend with him that contendeth with thee, and I will save thy children.", "web": "But thus says Yahweh, “Even the captives of the mighty shall be taken away, and the plunder of the terrible shall be delivered; for I will contend with him who contends with you, and I will save your children.", "bsb": "Indeed, this is what the LORD says: “Even the captives of the mighty will be taken away, and the plunder of the tyrant will be retrieved; I will contend with those who contend with you, and I will save your children.", "asv": "But thus saith Jehovah, Even the captives of the mighty shall be taken away, and the prey of the terrible shall be delivered; for I will contend with him that contendeth with thee, and I will save thy children.", "ylt": "For thus said Jehovah: Even the captive of the mighty is taken, And the prey of the terrible is delivered, And with thy striver I strive, and thy sons I save.", "dra": "For thus saith the Lord: Yea verily, even the captivity shall be taken away from the strong: and that which was taken by the mighty, shall be delivered. But I will judge those that have judged thee, and thy children I will save.", "bbe": "But the Lord says, Even the prisoners of the strong will be taken from him, and the cruel made to let go his goods: for I will take up your cause against your haters, and I will keep your children safe.", "geneva": "But thus sayeth the Lord, euen the captiuitie of the mightie shall be taken away: and the pray of the tyrant shall be deliuered: for I wil contend with him that contendeth with thee, and I will saue thy children,", "wycliffe": "For the Lord seith these thingis, Sotheli and caitifte schal be takun awey fro the stronge man, and that that is takun awei of a stalworthe man, schal be saued. Forsothe Y schal deme hem, that demyden thee, and Y schal saue thi sones.", "rotherham": "Surely, thus, saith Yahweh—Even the captive of the mighty one, shall be taken away, And the prey of the tyrant, be delivered; And thine opposers, I, will oppose, And thy children, I, will save;", "darby": "For thus saith Jehovah: Even the captive of the mighty shall be taken away, and the prey of the terrible shall be delivered; and I will strive with him that striveth with thee, and I will save thy children.", "twenty": "", "jps": "But thus saith HaShem: even the captives of the mighty shall be taken away, and the prey of the terrible shall be delivered; and I will contend with him that contendeth with thee, and I will save thy children.", "acv": "But thus says Jehovah, Even the captives of the mighty shall be taken away, and the prey of the terrible shall be delivered. For I will contend with him who contends with thee, and I will save thy sons.", "anderson": "", "haweis": "", "noyes": "Yea, thus saith Jehovah, The prey shall be taken away from the mighty, And the spoil of the terrible shall be rescued; For with him that contendeth with thee will I contend,", "webster": "But thus saith the LORD, Even the captives of the mighty shall be taken away, and the prey of the terrible shall be delivered: for I will contend with him that contendeth with thee, and I will save thy children.", "vulgate": "quia haec dicit Dominus equidem et captivitas a forte tolletur et quod ablatum fuerit a robusto salvabitur eos vero qui iudicaverunt te ego iudicabo et filios tuos ego salvabo;", "brenton": "For thus saith the Lord, If one should take a giant captive, he shall take spoils, and he who takes them from a mighty man shall be delivered: for I will plead thy cause, and I will deliver thy children."}}, {"v": 26, "ref": "49:26", "o": "וְ/הַאֲכַלְתִּ֤י אֶת מוֹנַ֨יִ/ךְ֙ אֶת בְּשָׂרָ֔/ם וְ/כֶ/עָסִ֖יס דָּמָ֣/ם יִשְׁכָּר֑וּ/ן וְ/יָדְע֣וּ כָל בָּשָׂ֗ר כִּ֣י אֲנִ֤י יְהוָה֙ מֽוֹשִׁיעֵ֔/ךְ וְ/גֹאֲלֵ֖/ךְ אֲבִ֥יר יַעֲקֹֽב", "en": {"kjv": "And I will feed them that oppress thee with their own flesh; and they shall be drunken with their own blood, as with sweet wine: and all flesh shall know that I the Lord am thy Saviour and thy Redeemer, the mighty One of Jacob.", "web": "I will feed those who oppress you with their own flesh; and they shall be drunken with their own blood, as with sweet wine: and all flesh shall know that I, Yahweh, am your Savior, and your Redeemer, the Mighty One of Jacob.”", "bsb": "I will make your oppressors eat their own flesh; they will be drunk on their own blood, as with wine. Then all mankind will know that I, the LORD, am your Savior and your Redeemer, the Mighty One of Jacob.”", "asv": "And I will feed them that oppress thee with their own flesh; and they shall be drunken with their own blood, as with sweet wine: and all flesh shall know that I, Jehovah, am thy Saviour, and thy Redeemer, the Mighty One of Jacob.", "ylt": "And I have caused thine oppressors to eat their own flesh, And as new wine they drink their own blood, And known have all flesh that I, Jehovah, Thy saviour, and thy redeemer, Am the Mighty One of Jacob!'", "dra": "And I will feed thy enemies with their own flesh: and they shall be made drunk with their own blood, as with new wine: and all flesh shall know, that I am the Lord that save thee, and thy Redeemer the Mighty One of Jacob.", "bbe": "And the flesh of your attackers will be taken by themselves for food; and they will take their blood for drink, as if it was sweet wine: and all men will see that I the Lord am your saviour, even he who takes up your cause, the Strong One of Jacob.", "geneva": "And will feede them that spoile thee, with their owne flesh, and they shall be drunken with their owne bloode, as with sweete wine: and all flesh shall know that I the Lord am thy sauiour and thy redeemer, the mighty one of Iaakob.", "wycliffe": "And Y schal fede thin enemyes with her fleischis, and thei schulen be greetli fillid with her blood as with must; and eche man schal wite, that Y am the Lord, sauynge thee, and thin ayenbiere, the strong of Jacob.", "rotherham": "Then will I feed thy tormentors with their own flesh, And as with new wine—with their own blood, shall they be drunk,—So shall all flesh, know, that, I—Yahweh, am thy Saviour, And, thy Redeemer, is the Mighty One of Jacob.", "darby": "And I will feed them that oppress thee with their own flesh; and they shall be drunken with their own blood, as with new wine. And all flesh shall know that I, Jehovah, [am] thy Saviour and thy Redeemer, the Mighty One of Jacob.", "twenty": "", "jps": "And I will feed them that oppress thee with their own flesh; and they shall be drunken with their own blood, as with sweet wine; and all flesh shall know that I HaShem am thy Saviour, and thy Redeemer, the Mighty One of Jacob.", "acv": "And I will feed those who oppress thee with their own flesh. And they shall be drunken with their own blood, as with sweet wine. And all flesh shall know that I, Jehovah, am thy Savior and thy Redeemer, the Mighty One of Jacob.", "anderson": "", "haweis": "", "noyes": "And I will save thy children. And I will cause thine oppressors to eat their own flesh; With their own blood shall they be drunk, as with new wine; And all flesh shall know that I Jehovah am thy saviour; That thy redeemer is the Mighty One of Jacob.", "webster": "And I will feed them that oppress thee with their own flesh; and they shall be drunken with their own blood, as with sweet wine: and all flesh shall know that I the LORD [am] thy Savior and thy Redeemer, the mighty One of Jacob.", "vulgate": "et cibabo hostes tuos carnibus suis et quasi musto sanguine suo inebriabuntur et sciet omnis caro quia ego Dominus salvans te et redemptor tuus Fortis Iacob;", "brenton": "And they that afflicted thee shall eat their own flesh; and they shall drink their own blood as new wine, and shall be drunken: and all flesh shall perceive that I am the Lord that delivers thee, and that upholds the strength of Jacob."}}]}, {"c": 50, "verses": [{"v": 1, "ref": "50:1", "o": "כֹּ֣ה אָמַ֣ר יְהוָ֗ה אֵ֣י זֶ֠ה סֵ֣פֶר כְּרִית֤וּת אִמְּ/כֶם֙ אֲשֶׁ֣ר שִׁלַּחְתִּ֔י/הָ א֚וֹ מִ֣י מִ/נּוֹשַׁ֔/י אֲשֶׁר מָכַ֥רְתִּי אֶתְ/כֶ֖ם ל֑/וֹ הֵ֤ן בַּ/עֲוֺנֹֽתֵי/כֶם֙ נִמְכַּרְתֶּ֔ם וּ/בְ/פִשְׁעֵי/כֶ֖ם שֻׁלְּחָ֥ה אִמְּ/כֶֽם", "en": {"kjv": "Thus saith the Lord, Where is the bill of your mother’s divorcement, whom I have put away? or which of my creditors is it to whom I have sold you? Behold, for your iniquities have ye sold yourselves, and for your transgressions is your mother put away.", "web": "Thus says Yahweh, “Where is the bill of your mother’s divorce, with which I have put her away? or which of my creditors is it to whom I have sold you? Behold, for your iniquities were you sold, and for your transgressions was your mother put away.", "bsb": "This is what the LORD says: “Where is your mother’s certificate of divorce with which I sent her away? Or to which of My creditors did I sell you? Look, you were sold for your iniquities, and for your transgressions your mother was sent away.", "asv": "Thus saith Jehovah, Where is the bill of your mother’s divorcement, wherewith I have put her away? or which of my creditors is it to whom I have sold you? Behold, for your iniquities were ye sold, and for your transgressions was your mother put away.", "ylt": "Thus said Jehovah: `Where is this--the bill of your mother's divorce, Whom I sent away? Or to which of My creditors have I sold you? Lo, for your iniquities ye have been sold, And for your transgressions Hath your mother been sent away.", "dra": "Thus saith the Lord: What is this bill of the divorce of your mother, with which I have put her away? or who is my creditor, to whom I sold you: behold you are sold for your iniquities, and for your wicked deeds have I put your mother away.", "bbe": "This is the word of the Lord: Where is the statement which I gave your mother when I put her away? or to which of my creditors have I given you for money? It was for your sins that you were given into the hands of others, and for your evil-doing was your mother put away.", "geneva": "Thus sayeth the Lord, Where is that bill of your mothers diuorcement, whome I haue cast off? or who is the creditour to whome I solde you? Beholde, for your iniquities are yee solde, and because of your transgressions is your mother forsaken.", "wycliffe": "The Lord seith these thingis, What is this book of forsakyng of youre modir, bi which Y lefte her? ether who is he, to whom Y owe, to whom Y seeld you? For lo! ye ben seeld for youre wickidnessis, and for youre grete trespassis Y lefte youre modir.", "rotherham": "Thus, saith Yahweh—Where then is the scroll of your mother’s divorce, whom I have put away? Or, which of my creditors, is it to whom I have sold you? Lo! for your iniquities, have ye been sold, And for your transgressions, hath your mother been put away.", "darby": "Thus saith Jehovah: Where is the bill of your mother's divorce, whom I have put away? or which of my creditors is it to whom I have sold you? Behold, through your iniquities have ye sold yourselves, and for your transgressions is your mother put away.", "twenty": "", "jps": "Thus saith HaShem: Where is the bill of your mother's divorcement, wherewith I have put her away? Or which of My creditors is it to whom I have sold you? Behold, for your iniquities were ye sold, and for your transgressions was your mother put away.", "acv": "Thus says Jehovah, Where is the bill of your mother's divorcement, with which I have put her away? Or which of my creditors is it to whom I have sold you? Behold, for your iniquities ye were sold, and for your transgressions your mother was put away.", "anderson": "", "haweis": "", "noyes": "Thus saith Jehovah: Where is the bill of your mother’s divorcement, By which I dismissed her? Or who is he among my creditors To whom I have sold you? Behold, for your iniquities are ye sold, And for your transgressions was your mother dismissed.", "webster": "Thus saith the LORD, Where [is] the bill of your mother's divorcement, whom I have put away? or which of my creditors [is it] to whom I have sold you? Behold, for your iniquities have ye sold yourselves, and for your transgressions is your mother put away.", "vulgate": "haec dicit Dominus quis est hic liber repudii matris vestrae quo dimisi eam aut quis est creditor meus cui vendidi vos ecce in iniquitatibus vestris venditi estis et in sceleribus vestris dimisi matrem vestram;", "brenton": "Thus saith the Lord, Of what kind is your mother's bill of divorcement, by which I put her away? or to which debtor have I sold you? Behold, ye are sold for your sins, and for your iniquities have I put your mother away."}}, {"v": 2, "ref": "50:2", "o": "מַדּ֨וּעַ בָּ֜אתִי וְ/אֵ֣ין אִ֗ישׁ קָרָֽאתִי֮ וְ/אֵ֣ין עוֹנֶה֒ הֲ/קָצ֨וֹר קָצְרָ֤ה יָדִ/י֙ מִ/פְּד֔וּת וְ/אִם אֵֽין בִּ֥/י כֹ֖חַ לְ/הַצִּ֑יל הֵ֣ן בְּ/גַעֲרָתִ֞/י אַחֲרִ֣יב יָ֗ם אָשִׂ֤ים נְהָרוֹת֙ מִדְבָּ֔ר תִּבְאַ֤שׁ דְּגָתָ/ם֙ מֵ/אֵ֣ין מַ֔יִם וְ/תָמֹ֖ת בַּ/צָּמָֽא", "en": {"kjv": "Wherefore, when I came, was there no man? when I called, was there none to answer? Is my hand shortened at all, that it cannot redeem? or have I no power to deliver? behold, at my rebuke I dry up the sea, I make the rivers a wilderness: their fish stinketh, because there is no water, and dieth for thirst.", "web": "Why, when I came, was there no man? when I called, was there no one to answer? Is my hand shortened at all, that it can’t redeem? or have I no power to deliver? Behold, at my rebuke I dry up the sea, I make the rivers a wilderness: their fish stink, because there is no water, and die for thirst.", "bsb": "Why was no one there when I arrived? Why did no one answer when I called? Is My hand too short to redeem you? Or do I lack the strength to deliver you? Behold, My rebuke dries up the sea; I turn the rivers into a desert; the fish rot for lack of water and die of thirst.", "asv": "Wherefore, when I came, was there no man? when I called, was there none to answer? Is my hand shortened at all, that it cannot redeem? or have I no power to deliver? Behold, at my rebuke I dry up the sea, I make the rivers a wilderness: their fish stink, because there is no water, and die for thirst.", "ylt": "Wherefore have I come, and there is no one? I called, and there is none answering, Hath My hand been at all short of redemption? And is there not in me power to deliver? Lo, by My rebuke I dry up a sea, I make rivers a wilderness, Their fish stinketh, for there is no water, And dieth with thirst.", "dra": "Because I came, and there was not a man: I called, and there was none that would hear. Is my hand shortened and become little, that I cannot redeem? or is there no strength in me to deliver? Behold at my rebuke I will make the sea a desert, I will turn the rivers into dry land: the fishes shall rot for want of water, and shall die for thirst.", "bbe": "Why, then, when I came, was there no man? and no one to give answer to my voice? has my hand become feeble, so that it is unable to take up your cause? or have I no power to make you free? See, at my word the sea becomes dry, I make the rivers a waste land: their fish are dead for need of water, and make an evil smell.", "geneva": "Wherefore came I, and there was no man? I called, and none answered: is mine hand so shortened, that it cannot helpe? or haue I no power to deliuer? Beholde, at my rebuke I drie vp the Sea: I make the floods desert: their fish rotteth for want of water, and dieth for thirst.", "wycliffe": "For Y cam, and no man was; Y clepide, and noon was that herde. Whether myn hond is abreggid, and maad litil, that Y mai not ayenbie? ether vertu is not in me for to delyuere? Lo! in my blamyng Y schal make the see forsakun, `ether desert, Y schal sette floodis in the drie place; fischis without watir schulen wexe rotun, and schulen dye for thirst.", "rotherham": "Wherefore, When I came in, was there no one? When I called, was there none to answer? Is mine own hand, really shortened, that it cannot redeem? Or is there not, in me, strength to deliver? Lo! by my rebuke, I dry up the sea I make rivers a desert, Their fish Stinketh, for want of water, Yea dieth, for thirst:", "darby": "Wherefore did I come, and there was no man? I called, and there was none to answer? Is my hand at all shortened that I cannot redeem, or have I no power to deliver? behold, at my rebuke I dry up the sea, I make rivers a wilderness; their fish stink because there is no water, and die for thirst.", "twenty": "", "jps": "Wherefore, when I came, was there no man? when I called, was there none to answer? Is My hand shortened at all, that it cannot redeem? Or have I no power to deliver? Behold, at My rebuke I dry up the sea, I make the rivers a wilderness; their fish become foul, because there is no water, and die for thirst.", "acv": "Why, when I came, was there no man? When I called, was there none to answer? Is my hand shortened at all, that it cannot redeem? Or have I no power to deliver? Behold, at my rebuke I dry up the sea. I make the rivers a wilderness. Their fish stink because there is no water, and die for thirst.", "anderson": "", "haweis": "", "noyes": "Wherefore, when I came, was no man at hand? When I called, was there none to answer? Is my hand too short to redeem? Or have I no power to deliver? Behold, at my rebuke I dry up the sea, And make the rivers a desert. Their fish putrefy for want of water, And die with thirst.", "webster": "Why, when I came, [was there] no man? when I called, [was there] none to answer? Is my hand shortened at all, that it cannot redeem? or have I no power to deliver? behold, at my rebuke I dry up the sea, I make the rivers a wilderness: their fish becometh putrid, because [there is] no water, and dieth for thirst.", "vulgate": "quia veni et non erat vir vocavi et non erat qui audiret numquid adbreviata et parvula facta est manus mea ut non possim redimere aut non est in me virtus ad liberandum ecce in increpatione mea desertum faciam mare ponam flumina in siccum conputrescent pisces sine aqua et morientur in siti;", "brenton": "Why did I come, and there was no man? why did I call, and there was none to hearken? Is not my hand strong to redeem? or can I not deliver? behold, by my rebuke I will dry up the sea, and make rivers a wilderness; and their fish shall be dried up because there is no water, and shall die for thirst."}}, {"v": 3, "ref": "50:3", "o": "אַלְבִּ֥ישׁ שָׁמַ֖יִם קַדְר֑וּת וְ/שַׂ֖ק אָשִׂ֥ים כְּסוּתָֽ/ם", "en": {"kjv": "I clothe the heavens with blackness, and I make sackcloth their covering.", "web": "I clothe the heavens with blackness, and I make sackcloth their covering.”", "bsb": "I clothe the heavens in black and make sackcloth their covering.”", "asv": "I clothe the heavens with blackness, and I make sackcloth their covering.", "ylt": "I clothe the heavens with blackness, And sackcloth I make their covering.", "dra": "I will clothe the heavens with darkness, and will make sackcloth their covering.", "bbe": "By me the heavens are clothed with black, and I make haircloth their robe.", "geneva": "I clothe the heauens with darkenesse, and make a sacke their couering.", "wycliffe": "Y schal clothe heuenes with derknessis, and Y schal sette a sak the hilyng of tho.", "rotherham": "I clothe the heavens with gloom, And, of sackcloth, make I their covering.", "darby": "I clothe the heavens with blackness, and I make sackcloth their covering.", "twenty": "", "jps": "I clothe the heavens with blackness, and I make sackcloth their covering.", "acv": "I clothe the heavens with blackness, and I make sackcloth their covering.", "anderson": "", "haweis": "", "noyes": "I clothe the heavens with blackness, And make sackcloth their covering.", "webster": "I clothe the heavens with blackness, and I make sackcloth their covering.", "vulgate": "induam caelos tenebris et saccum ponam operimentum eorum;", "brenton": "I will clothe the sky with darkness, and will make its covering as sackcloth."}}, {"v": 4, "ref": "50:4", "o": "אֲדֹנָ֣/י יְהֹוִ֗ה נָ֤תַן לִ/י֙ לְשׁ֣וֹן לִמּוּדִ֔ים לָ/דַ֛עַת לָ/ע֥וּת אֶת יָעֵ֖ף דָּבָ֑ר יָעִ֣יר בַּ/בֹּ֣קֶר בַּ/בֹּ֗קֶר יָעִ֥יר לִ/י֙ אֹ֔זֶן לִ/שְׁמֹ֖עַ כַּ/לִּמּוּדִֽים", "en": {"kjv": "The Lord God hath given me the tongue of the learned, that I should know how to speak a word in season to him that is weary: he wakeneth morning by morning, he wakeneth mine ear to hear as the learned.", "web": "The Lord Yahweh has given me the tongue of those who are taught, that I may know how to sustain with words him who is weary: he wakens morning by morning, he wakens my ear to hear as those who are taught.", "bsb": "The Lord GOD has given Me the tongue of discipleship, to sustain the weary with a word. He awakens Me morning by morning; He awakens My ear to listen as a disciple.", "asv": "The Lord Jehovah hath given me the tongue of them that are taught, that I may know how to sustain with words him that is weary: he wakeneth morning by morning, he wakeneth mine ear to hear as they that are taught.", "ylt": "The Lord Jehovah hath given to me The tongue of taught ones, To know to aid the weary by a word, He waketh morning by morning, He waketh for me an ear to hear as taught ones.", "dra": "The Lord hath given me a learned tongue, that I should know how to uphold by word him that is weary: he wakeneth in the morning, in the morning he wakeneth my ear, that I may hear him as a master.", "bbe": "The Lord God has given me the tongue of those who are experienced, so that I may be able to give the word a special sense for the feeble: every morning my ear is open to his teaching, like those who are experienced:", "geneva": "The Lord God hath giuen me a tongue of the learned, that I shoulde knowe to minister a woord in time to him that is weary: he will raise me vp in the morning: in the morning hee will waken mine eare to heare, as the learned.", "wycliffe": "The Lord yaf to me a lerned tunge, that Y kunne susteyne hym bi word that failide; erli the fadir reisith, erli he reisith an eere to me, that Y here as a maister.", "rotherham": "My Lord Yahweh, hath given unto me the tongue of the instructed, That I should know how to succour the fainting, with discourse,—He kept wakening—morning by morning. He kept wakening mine ear, to hearken as do the instructed;", "darby": "The Lord Jehovah hath given me the tongue of the instructed, that I should know how to succour by a word him that is weary. He wakeneth morning by morning, he wakeneth mine ear to hear as the instructed.", "twenty": "", "jps": "The L-rd GOD hath given me the tongue of them that are taught, that I should know how to sustain with words him that is weary; He wakeneth morning by morning, He wakeneth mine ear to hear as they that are taught.", "acv": "The lord Jehovah has given me the tongue of those who are taught, that I may know how to sustain with words him who is weary. He awakens morning by morning. He awakens my ear to hear as those who are taught.", "anderson": "", "haweis": "", "noyes": "The Lord Jehovah hath given me the tongue of the learned, That I might know how to strengthen with my words them that are weary; He wakeneth me every morning, He wakeneth mine ear, That I may hear in the manner of the learned.", "webster": "The Lord GOD hath given me the tongue of the learned, that I should know how to speak a word in season to [him that is] weary: he wakeneth morning by morning, he wakeneth my ear to hear as the learned.", "vulgate": "Dominus dedit mihi linguam eruditam ut sciam sustentare eum qui lassus est verbo erigit mane mane erigit mihi aurem ut audiam quasi magistrum;", "brenton": "The Lord even God gives me the tongue of instruction, to know when it is fit to speak a word: he has appointed for me early, he has given me an ear to hear:"}}, {"v": 5, "ref": "50:5", "o": "אֲדֹנָ֤/י יְהוִה֙ פָּתַֽח לִ֣/י אֹ֔זֶן וְ/אָנֹכִ֖י לֹ֣א מָרִ֑יתִי אָח֖וֹר לֹ֥א נְסוּגֹֽתִי", "en": {"kjv": "The Lord God hath opened mine ear, and I was not rebellious, neither turned away back.", "web": "The Lord Yahweh has opened my ear, and I was not rebellious, neither turned away backward.", "bsb": "The Lord GOD has opened My ears, and I have not been rebellious, nor have I turned back.", "asv": "The Lord Jehovah hath opened mine ear, and I was not rebellious, neither turned away backward.", "ylt": "The Lord Jehovah opened for me the ear, And I rebelled not--backward I moved not.", "dra": "The Lord God hath opened my ear, and I do not resist: I have not gone back.", "bbe": "And I have not put myself against him, or let my heart be turned back from him.", "geneva": "The Lord God hath opened mine eare and I was not rebellious, neither turned I backe.", "wycliffe": "The Lord God openede an eere to me; forsothe Y ayenseie not, Y yede not abak.", "rotherham": "My Lord, Yahweh, opened mine ear, And, I, was not rebellious,—Away, turned I not:", "darby": "The Lord Jehovah hath opened mine ear, and I was not rebellious; I turned not away back.", "twenty": "", "jps": "The L-rd GOD hath opened mine ear, and I was not rebellious, neither turned away backward.", "acv": "The lord Jehovah has opened my ear, and I was not rebellious, nor turned away backward.", "anderson": "", "haweis": "", "noyes": "The Lord Jehovah opened mine ear, And I was not disobedient, Neither did I withdraw myself backward.", "webster": "The Lord GOD opened my ear, and I was not rebellious, neither turned away back.", "vulgate": "Dominus Deus aperuit mihi aurem ego autem non contradico retrorsum non abii;", "brenton": "and the instruction of the Lord, even the Lord, opens mine ears, and I do not disobey, nor dispute."}}, {"v": 6, "ref": "50:6", "o": "גֵּוִ/י֙ נָתַ֣תִּי לְ/מַכִּ֔ים וּ/לְחָיַ֖/י לְ/מֹֽרְטִ֑ים פָּנַ/י֙ לֹ֣א הִסְתַּ֔רְתִּי מִ/כְּלִמּ֖וֹת וָ/רֹֽק", "en": {"kjv": "I gave my back to the smiters, and my cheeks to them that plucked off the hair: I hid not my face from shame and spitting.", "web": "I gave my back to the strikers, and my cheeks to those who plucked off the hair; I didn’t hide my face from shame and spitting.", "bsb": "I offered My back to those who struck Me, and My cheeks to those who tore out My beard. I did not hide My face from scorn and spittle.", "asv": "I gave my back to the smiters, and my cheeks to them that plucked off the hair; I hid not my face from shame and spitting.", "ylt": "My back I have given to those smiting, And my cheeks to those plucking out, My face I hid not from shame and spitting.", "dra": "I have given my body to the strikers, and my cheeks to them that plucked them: I have not turned away my face from them that rebuked me, and spit upon me.", "bbe": "I was offering my back to those who gave me blows, and my face to those who were pulling out my hair: I did not keep my face covered from marks of shame.", "geneva": "I gaue my backe vnto the smiters, and my cheekes to the nippers: I hidde not my face from shame and spitting.", "wycliffe": "I yaf my bodi to smyteris, and my chekis to pulleris; Y turnede not a wei my face fro men blamynge, and spetynge on me.", "rotherham": "My back, gave I to smiters, and My cheeks, to them who pulled out the beard,—My face, hid I not from insult and spitting.", "darby": "I gave my back to smiters, and my cheeks to them that plucked off the hair; I hid not my face from shame and spitting.", "twenty": "", "jps": "I gave my back to the smiters, and my checks to them that plucked off the hair; I hid not my face from shame and spitting.", "acv": "I gave my back to the smiters, and my cheeks to those who plucked off the hair. I did not hide my face from shame and spitting.", "anderson": "", "haweis": "", "noyes": "I gave my back to the smiters, And my cheeks to them that pluck the beard; I hid not my face from shame and spitting.", "webster": "I gave my back to the smiters, and my cheeks to them that plucked off the hair: I hid not my face from shame and spitting.", "vulgate": "corpus meum dedi percutientibus et genas meas vellentibus faciem meam non averti ab increpantibus et conspuentibus;", "brenton": "I gave my back to scourges, and my cheeks to blows; and I turned not away my face from the shame of spitting:"}}, {"v": 7, "ref": "50:7", "o": "וַ/אדֹנָ֤/י יְהוִה֙ יַֽעֲזָר לִ֔/י עַל כֵּ֖ן לֹ֣א נִכְלָ֑מְתִּי עַל כֵּ֞ן שַׂ֤מְתִּי פָנַ/י֙ כַּֽ/חַלָּמִ֔ישׁ וָ/אֵדַ֖ע כִּי לֹ֥א אֵבֽוֹשׁ", "en": {"kjv": "For the Lord God will help me; therefore shall I not be confounded: therefore have I set my face like a flint, and I know that I shall not be ashamed.", "web": "For the Lord Yahweh will help me; therefore I have not been confounded: therefore have I set my face like a flint, and I know that I shall not be disappointed.", "bsb": "Because the Lord GOD helps Me, I have not been disgraced; therefore I have set My face like flint, and I know that I will not be put to shame.", "asv": "For the Lord Jehovah will help me; therefore have I not been confounded: therefore have I set my face like a flint, and I know that I shall not be put to shame.", "ylt": "And the Lord Jehovah giveth help to me, Therefore I have not been ashamed, Therefore I have set my face as a flint, And I know that I am not ashamed.", "dra": "The Lord God is my helper, therefore am I not confounded: therefore have I set my face as a most hard rock, and I know that I shall not be confounded.", "bbe": "For the Lord God is my helper; I will not be put to shame: so I have made my face like a rock, and I am certain that he will give me my right.", "geneva": "For the Lord God will helpe me, therefore shall I not bee confounded: therefore haue I set my face like a flint, and I knowe that I shall not be ashamed.", "wycliffe": "The Lord God is myn helpere, and therfor Y am not schent; therfor Y haue set my face as a stoon maad hard, and Y woot that Y schal not be schent.", "rotherham": "Because, My Lord, Yahweh, would help me, Therefore was I not deterred by insult,—Therefore did I set my face like flint, And I knew that I should not be put to shame.", "darby": "But the Lord Jehovah will help me: therefore shall I not be confounded; therefore have I set my face like a flint, and I know that I shall not be ashamed.", "twenty": "", "jps": "For the L-rd GOD will help me; therefore have I not been confounded; therefore have I set my face like a flint, and I know that I shall not be ashamed.", "acv": "For the lord Jehovah will help me. Therefore I have not been confounded. Therefore I have set my face like a flint, and I know that I shall not be put to shame.", "anderson": "", "haweis": "", "noyes": "But the Lord Jehovah is my helper, Therefore shall I not be confounded; Therefore have I made my face like a flint, For I know that I shall not be put to shame.", "webster": "For the Lord GOD will help me; therefore shall I not be confounded: therefore have I set my face like a flint, and I know that I shall not be ashamed.", "vulgate": "Dominus Deus auxiliator meus ideo non sum confusus ideo posui faciem meam ut petram durissimam et scio quoniam non confundar;", "brenton": "but the Lord God became my helper; therefore I was not ashamed, but I set my face as a solid rock; and I know that I shall never be ashamed,"}}, {"v": 8, "ref": "50:8", "o": "קָרוֹב֙ מַצְדִּיקִ֔/י מִֽי יָרִ֥יב אִתִּ֖/י נַ֣עַמְדָה יָּ֑חַד מִֽי בַ֥עַל מִשְׁפָּטִ֖/י יִגַּ֥שׁ אֵלָֽ/י", "en": {"kjv": "He is near that justifieth me; who will contend with me? let us stand together: who is mine adversary? let him come near to me.", "web": "He is near who justifies me; who will bring charges against me? Let us stand up together: who is my adversary? Let him come near to me.", "bsb": "The One who vindicates Me is near. Who will dare to contend with Me? Let us confront each other! Who has a case against Me? Let him approach Me!", "asv": "He is near that justifieth me; who will contend with me? let us stand up together: who is mine adversary? let him come near to me.", "ylt": "Near is He who is justifying me, Who doth contend with me? We stand together, who is mine opponent? Let him come nigh unto me.", "dra": "He is near that justifieth me, who will contend with me? let us stand together, who is my adversary? let him come near to me.", "bbe": "He who takes up my cause is near; who will go to law with me? let us come together before the judge: who is against me? let him come near to me.", "geneva": "Hee is neere that iustifieth mee: who will contend with me? Let vs stande together: who is mine aduersarie? let him come neere to me.", "wycliffe": "He is niy, that iustifieth me; who ayenseith me? stonde we togidere. Who is myn aduersarie? neiye he to me.", "rotherham": "At hand, is one who can justify me. Who will contend with me? let, us stand forth together,—Who can accuse me? let him draw near to me!", "darby": "He is near that justifieth me: who will contend with me? let us stand together; who is mine adverse party? let him draw near unto me.", "twenty": "", "jps": "He is near that justifieth me; who will contend with me? let us stand up together; who is mine adversary? let him come near to me.", "acv": "He is near who justifies me. Who will contend with me? Let us stand up together. Who is my adversary? Let him come near to me.", "anderson": "", "haweis": "", "noyes": "He that defendeth my cause is near; Who will contend with me? Let us stand up together! Who is my adversary? Let him come near to me!", "webster": "[He is] near that justifieth me; who will contend with me? let us stand together; who [is] my adversary? let him come near to me.", "vulgate": "iuxta est qui iustificat me quis contradicet mihi stemus simul quis est adversarius meus accedat ad me;", "brenton": "for he that has justified me draws near; who is he that pleads with me? let him stand up against me at the same time: yea, who is he that pleads with me? let him draw nigh to me."}}, {"v": 9, "ref": "50:9", "o": "הֵ֣ן אֲדֹנָ֤/י יְהוִה֙ יַֽעֲזָר לִ֔/י מִי ה֖וּא יַרְשִׁיעֵ֑/נִי הֵ֤ן כֻּלָּ/ם֙ כַּ/בֶּ֣גֶד יִבְל֔וּ עָ֖שׁ יֹאכְלֵֽ/ם", "en": {"kjv": "Behold, the Lord God will help me; who is he that shall condemn me? lo, they all shall wax old as a garment; the moth shall eat them up.", "web": "Behold, the Lord Yahweh will help me; who is he who shall condemn me? Behold, all they shall wax old as a garment, the moth shall eat them up.", "bsb": "Surely the Lord GOD helps Me. Who is there to condemn Me? See, they will all wear out like a garment; the moths will devour them.", "asv": "Behold, the Lord Jehovah will help me; who is he that shall condemn me? behold, they all shall wax old as a garment; the moth shall eat them up.", "ylt": "Lo, the Lord Jehovah giveth help to me, Who is he that declareth me wicked? Lo, all of them as a garment wear out, A moth doth eat them.", "dra": "Behold the Lord God is my helper: who is he that shall condemn me? Lo, they shall all be destroyed as a garment, the moth shall eat them up.", "bbe": "See, the Lord God is my helper; who will give a decision against me? truly, all of them will become old like a robe; they will be food for the worm.", "geneva": "Beholde, the Lord God will helpe me: who is he that can condemne me? loe, they shall waxe olde as a garment: the mothe shall eate them vp.", "wycliffe": "Lo! the Lord God is myn helpere; who therfor is he that condempneth me? Lo! alle schulen be defoulid as a cloth, and a mouyte schal ete hem.", "rotherham": "Lo! My Lord, Yahweh, will help me, Who is he that shall prove me lawless? Lo! they all, as a garment, shall fall to pieces, the moth shall consume them.", "darby": "Behold, the Lord Jehovah will help me; who is he that shall condemn me? Behold, they all shall grow old as a garment; the moth shall eat them up.", "twenty": "", "jps": "Behold, the L-rd GOD will help me; who is he that shall condemn me? Behold, they all shall wax old as a garment, the moth shall eat them up.", "acv": "Behold, the lord Jehovah will help me. Who is he who shall condemn me? Behold, all they shall grow old as a garment; the moth shall eat them up.", "anderson": "", "haweis": "", "noyes": "Behold, the Lord Jehovah is my defender; Who is he that shall condemn me? Behold, they shall all waste away like a garment; The moth shall consume them.", "webster": "Behold the Lord GOD will help me; who [is] he [that] shall condemn me? lo, they all shall wax old as a garment; the moth shall eat them up.", "vulgate": "ecce Dominus Deus auxiliator meus quis est qui condemnet me ecce omnes quasi vestimentum conterentur tinea comedet eos;", "brenton": "Behold, the Lord, the Lord, will help me; who will hurt me? behold, all ye shall wax old as a garment, and a moth shall devour you."}}, {"v": 10, "ref": "50:10", "o": "מִ֤י בָ/כֶם֙ יְרֵ֣א יְהוָ֔ה שֹׁמֵ֖עַ בְּ/ק֣וֹל עַבְדּ֑/וֹ אֲשֶׁ֣ר הָלַ֣ךְ חֲשֵׁכִ֗ים וְ/אֵ֥ין נֹ֨גַהּ֙ ל֔/וֹ יִבְטַח֙ בְּ/שֵׁ֣ם יְהוָ֔ה וְ/יִשָּׁעֵ֖ן בֵּ/אלֹהָֽי/ו", "en": {"kjv": "Who is among you that feareth the Lord, that obeyeth the voice of his servant, that walketh in darkness, and hath no light? let him trust in the name of the Lord, and stay upon his God.", "web": "Who is among you who fears Yahweh, who obeys the voice of his servant? He who walks in darkness, and has no light, let him trust in Yahweh’s name, and rely on his God.", "bsb": "Who among you fears the LORD and obeys the voice of His Servant? Who among you walks in darkness and has no light? Let him trust in the name of the LORD; let him lean on his God.", "asv": "Who is among you that feareth Jehovah, that obeyeth the voice of his servant? he that walketh in darkness, and hath no light, let him trust in the name of Jehovah, and rely upon his God.", "ylt": "Who is among you, fearing Jehovah, Hearkening to the voice of His servant, That hath walked in dark places, And there is no brightness for him? Let him trust in the name of Jehovah, And lean upon his God.", "dra": "Who is there among you that feareth the Lord, that heareth the voice of his servant, that hath walked in darkness, and hath no light? let him hope in the name of the Lord, and lean upon his God.", "bbe": "Who among you has the fear of the Lord, giving ear to the voice of his servant who has been walking in the dark and has no light? Let him put his faith in the name of the Lord, looking to his God for support.", "geneva": "Who is among you that feareth the Lord? let him heare the voyce of his seruant: hee that walketh in darkenesse, and hath no light, let him trust in the Name of the Lord, and staye vpon his God.", "wycliffe": "Who of you dredith the Lord, and herith the vois of his seruaunt? Who yede in dercnessis and liyt is not to hym, hope he in the name of the Lord, and triste he on his God.", "rotherham": "Who among you, revereth Yahweh, Hearkening unto the voice of his Servant,—That hath walked in dark places And hath had no gleam of light? Let him trust in the name of Yahweh, And lean upon his God.", "darby": "Who is among you that feareth Jehovah, that hearkeneth to the voice of his servant? he that walketh in darkness, and hath no light, — let him confide in the name of Jehovah, and stay himself upon hisGod.", "twenty": "", "jps": "Who is among you that feareth HaShem, that obeyeth the voice of His servant? though he walketh in darkness, and hath no light, let him trust in the name of HaShem, and stay upon his G-d.", "acv": "Who is among you that fears Jehovah, who obeys the voice of his servant? He who walks in darkness, and has no light, let him trust in the name of Jehovah, and rely upon his God.", "anderson": "", "haweis": "", "noyes": "Who is there among you that feareth Jehovah, That hearkeneth to the voice of his servant, That walketh in darkness and hath no light? Let him trust in the name of Jehovah, And lean upon his God.", "webster": "Who [is] among you that feareth the LORD, that obeyeth the voice of his servant, that walketh [in] darkness, and hath no light? let him trust in the name of the LORD, and rely upon his God.", "vulgate": "quis ex vobis timens Dominum audiens vocem servi sui qui ambulavit in tenebris et non est lumen ei speret in nomine Domini et innitatur super Deum suum;", "brenton": "Who is among you that fears the Lord? let him hearken to the voice of his servant: ye that walk in darkness, and have no light, trust in the name of the Lord, and stay upon God."}}, {"v": 11, "ref": "50:11", "o": "הֵ֧ן כֻּלְּ/כֶ֛ם קֹ֥דְחֵי אֵ֖שׁ מְאַזְּרֵ֣י זִיק֑וֹת לְכ֣וּ בְּ/א֣וּר אֶשְׁ/כֶ֗ם וּ/בְ/זִיקוֹת֙ בִּֽעַרְתֶּ֔ם מִ/יָּדִ/י֙ הָיְתָה זֹּ֣את לָ/כֶ֔ם לְ/מַעֲצֵבָ֖ה תִּשְׁכָּבֽוּ/ן", "en": {"kjv": "Behold, all ye that kindle a fire, that compass yourselves about with sparks: walk in the light of your fire, and in the sparks that ye have kindled. This shall ye have of mine hand; ye shall lie down in sorrow.", "web": "Behold, all you who kindle a fire, who adorn yourselves with torches around yourselves; walk in the flame of your fire, and among the brands that you have kindled. You shall have this of my hand; you shall lie down in sorrow.", "bsb": "Behold, all you who kindle a fire, who array yourselves with firebrands, walk in the light of your fire and of the firebrands you have lit! This is what you will receive from My hand: You will lie down in a place of torment.", "asv": "Behold, all ye that kindle a fire, that gird yourselves about with firebrands; walk ye in the flame of your fire, and among the brands that ye have kindled. This shall ye have of my hand; ye shall lie down in sorrow.", "ylt": "Lo, all ye kindling a fire, girding on sparks, Walk ye in the light of your fire, And in the sparks ye have caused to burn, From my hand hath this been to you, In grief ye lie down!", "dra": "Behold all you that kindle a fire, encompassed with flames, walk in the light of your fire, and in the flames which you have kindled: this is done to you by my hand, you shall sleep in sorrows.", "bbe": "See, all you who make a fire, arming yourselves with burning branches: go in the flame of your fire, and among the branches you have put a light to. This will you have from my hand, you will make your bed in sorrow.", "geneva": "Beholde, all you kindle a fire, and are compassed about with sparkes: walke in the light of your fire, and in the sparkes that ye haue kindled. This shall ye haue of mine hand: ye shall lye downe in sorowe.", "wycliffe": "Lo! alle ye kyndlynge fier, and gird with flawmes, go in the liyt of youre fier, and in the flawmes whiche ye han kyndlid to you. This is maad of myn hond to you, ye schulen slepe in sorewis.", "rotherham": "Lo! all ye that kindle a fire, That gird yourselves with fiery darts,—Walk ye in the blaze of your own fire. And in the fiery darts ye have kindled, At my hand, hath this befallen you, In sorrow, shall ye lie down.", "darby": "Behold, all ye that kindle a fire, that compass yourselves about with sparks: walk in the light of your fire, and among the sparks [that] ye have kindled. This shall ye have of my hand: ye shall lie down in sorrow.", "twenty": "", "jps": "Behold, all ye that kindle a fire, that gird yourselves with firebrands, begone in the flame of your fire, and among the brands that ye have kindled. This shall ye have of My hand; ye shall lie down in sorrow.", "acv": "Behold, all ye who kindle a fire, who gird yourselves about with firebrands, walk ye in the flame of your fire, and among the brands that ye have kindled. This ye shall have from my hand. Ye shall lie down in sorrow.", "anderson": "", "haweis": "", "noyes": "Behold, all ye who kindle a fire, Who gird yourselves with burning arrows! Walk ye in the light of your fire, And in the burning arrows which ye have kindled. This shall ye have from my hand; Ye shall lie down in sorrow.", "webster": "Behold, all ye that kindle a fire, that encompass [yourselves] with sparks: walk in the light of your fire, and in the sparks [that] ye have kindled. This shall ye have of my hand; ye shall lie down in sorrow.", "vulgate": "ecce omnes vos accendentes ignem accincti flammis ambulate in lumine ignis vestri et in flammis quas succendistis de manu mea factum est hoc vobis in doloribus dormietis;", "brenton": "Behold, ye all kindle a fire, and feed a flame: walk in the light of your fire, and in the flame which ye have kindled. This has happened to you for my sake; ye shall lie down in sorrow."}}]}, {"c": 51, "verses": [{"v": 1, "ref": "51:1", "o": "שִׁמְע֥וּ אֵלַ֛/י רֹ֥דְפֵי צֶ֖דֶק מְבַקְשֵׁ֣י יְהוָ֑ה הַבִּ֨יטוּ֙ אֶל צ֣וּר חֻצַּבְתֶּ֔ם וְ/אֶל מַקֶּ֥בֶת בּ֖וֹר נֻקַּרְתֶּֽם", "en": {"kjv": "Hearken to me, ye that follow after righteousness, ye that seek the Lord: look unto the rock whence ye are hewn, and to the hole of the pit whence ye are digged.", "web": "“Listen to me, you who follow after righteousness, you who seek Yahweh: look to the rock you were cut from, and to the hold of the pit you were dug from.", "bsb": "“Listen to Me, you who pursue righteousness, you who seek the LORD: Look to the rock from which you were cut, and to the quarry from which you were hewn.", "asv": "Hearken to me, ye that follow after righteousness, ye that seek Jehovah: look unto the rock whence ye were hewn, and to the hole of the pit whence ye were digged.", "ylt": "Hearken unto Me, ye pursuing righteousness, Seeking Jehovah, Look attentively unto the rock--ye have been hewn, And unto the hole of the pit--ye have been digged.", "dra": "Give ear to me, you that follow that which is just, and you that seek the Lord: look unto the rock whence you are hewn, and to the hole of the pit from which you are dug out.", "bbe": "Give ear to me, you who are searching for righteousness, who are looking for the Lord: see the rock from which you were cut out, and the hole out of which you were taken.", "geneva": "Heare me, ye that follow after righteousnes, and ye that seeke the Lord: looke vnto the rocke, whence ye are hewen, and to the hole of the pit, whence ye are digged.", "wycliffe": "Here ye me, that suen that that is iust, and seken the Lord. Take ye hede to the stoon, fro whennys ye ben hewun doun, and to the caue of the lake, fro which ye ben kit doun.", "rotherham": "Hearken unto me, Ye that pursue righteousness, Ye that seek Yahweh,—Look well unto the rock whence ye were hewn, And unto the quarry whence ye were digged:", "darby": "Hearken unto me, ye that follow after righteousness, ye that seek Jehovah: look unto the rock [whence] ye were hewn, and to the hole of the pit [whence] ye were digged.", "twenty": "", "jps": "Hearken to Me, ye that follow after righteousness, ye that seek HaShem; look unto the rock whence ye were hewn, and to the hole of the pit whence ye were digged.", "acv": "Hearken to me, ye who follow after righteousness, ye who seek Jehovah. Look to the rock from where ye were hewn, and to the hold of the pit from where ye were dug.", "anderson": "", "haweis": "", "noyes": "Hearken to me, ye that pursue righteousness. Ye that seek Jehovah! Look to the rock whence ye were hewn, To the pit-quarry whence ye were digged!", "webster": "Hearken to me, ye that follow after righteousness, ye that seek the LORD: look to the rock [whence] ye are hewn, and to the hole of the pit [whence] ye are digged.", "vulgate": "audite me qui sequimini quod iustum est et quaeritis Dominum adtendite ad petram unde excisi estis et ad cavernam laci de qua praecisi estis;", "brenton": "Hearken to me, ye that follow after righteousness, and seek the Lord: look to the solid rock, which ye have hewn, and to the hole of the pit which ye have dug."}}, {"v": 2, "ref": "51:2", "o": "הַבִּ֨יטוּ֙ אֶל אַבְרָהָ֣ם אֲבִי/כֶ֔ם וְ/אֶל שָׂרָ֖ה תְּחוֹלֶלְ/כֶ֑ם כִּי אֶחָ֣ד קְרָאתִ֔י/ו וַ/אֲבָרְכֵ֖/הוּ וְ/אַרְבֵּֽ/הוּ", "en": {"kjv": "Look unto Abraham your father, and unto Sarah that bare you: for I called him alone, and blessed him, and increased him.", "web": "Look to Abraham your father, and to Sarah who bore you; for when he was but one I called him, and I blessed him, and made him many.", "bsb": "Look to Abraham your father, and to Sarah who gave you birth. When I called him, he was but one; then I blessed him and multiplied him.", "asv": "Look unto Abraham your father, and unto Sarah that bare you; for when he was but one I called him, and I blessed him, and made him many.", "ylt": "Look attentively unto Abraham your father, And unto Sarah--she bringeth you forth, For--one--I have called him, And I bless him, and multiply him.", "dra": "Look unto Abraham your father, and to Sara that bore you: for I called him alone, and blessed him, and multiplied him.", "bbe": "Let your thoughts be turned to Abraham, your father, and to Sarah, who gave you birth: for when he was but one, my voice came to him, and I gave him my blessing, and made him a great people.", "geneva": "Consider Abraham your father, and Sarah that bare you: for I called him alone, and blessed him, and increased him.", "wycliffe": "Take ye heede to Abraham, youre fadir, and to Sare, that childide you; for Y clepide hym oon, and Y blesside hym, and Y multipliede hym.", "rotherham": "Look well unto Abraham your father, And unto Sarah who gave you birth,—For he was, alone, when called I him, And, I blessed him that I might make him, many.", "darby": "Look unto Abraham your father, and unto Sarah that bore you; for I called him when he was alone, and blessed him, and multiplied him.", "twenty": "", "jps": "Look unto Abraham your father, and unto Sarah that bore you; for when he was but one I called him, and I blessed him, and made him many.", "acv": "Look to Abraham your father, and to Sarah who bore you. For when he was but one I called him, and I blessed him, and made him many.", "anderson": "", "haweis": "", "noyes": "Look to Abraham your father, And to Sarah that bore you! For I called him when only one, And blessed him, and multiplied him.", "webster": "Look to Abraham your father, and to Sarah [that] bore you: for I called him alone, and blessed him, and increased him.", "vulgate": "adtendite ad Abraham patrem vestrum et ad Sarram quae peperit vos quia unum vocavi eum et benedixi ei et multiplicavi eum;", "brenton": "Look to Abraam your father, and to Sarrha that bore you: for he was alone when I called him, and blessed him, and loved him, and multiplied him."}}, {"v": 3, "ref": "51:3", "o": "כִּֽי נִחַ֨ם יְהוָ֜ה צִיּ֗וֹן נִחַם֙ כָּל חָרְבֹתֶ֔י/הָ וַ/יָּ֤שֶׂם מִדְבָּרָ/הּ֙ כְּ/עֵ֔דֶן וְ/עַרְבָתָ֖/הּ כְּ/גַן יְהוָ֑ה שָׂשׂ֤וֹן וְ/שִׂמְחָה֙ יִמָּ֣צֵא בָ֔/הּ תּוֹדָ֖ה וְ/ק֥וֹל זִמְרָֽה", "en": {"kjv": "For the Lord shall comfort Zion: he will comfort all her waste places; and he will make her wilderness like Eden, and her desert like the garden of the Lord; joy and gladness shall be found therein, thanksgiving, and the voice of melody.", "web": "For Yahweh has comforted Zion; he has comforted all her waste places, and has made her wilderness like Eden, and her desert like the garden of Yahweh; joy and gladness shall be found therein, thanksgiving, and the voice of melody.", "bsb": "For the LORD will comfort Zion and will look with compassion on all her ruins; He will make her wilderness like Eden and her desert like the garden of the LORD. Joy and gladness will be found in her, thanksgiving and melodious song.", "asv": "For Jehovah hath comforted Zion; he hath comforted all her waste places, and hath made her wilderness like Eden, and her desert like the garden of Jehovah; joy and gladness shall be found therein, thanksgiving, and the voice of melody.", "ylt": "For Jehovah hath comforted Zion, He hath comforted all her wastes, And He setteth her wilderness as Eden, And her desert as a garden of Jehovah, Joy, yea, gladness is found in her, Confession, and the voice of song.", "dra": "The Lord therefore will comfort Sion, and will comfort all the ruins thereof: and he will make her desert as a place of pleasure, and her wilderness as the garden of the Lord. Joy and gladness shall be found therein, thanksgiving, and the voice of praise.", "bbe": "For the Lord has given comfort to Zion: he has made glad all her broken walls; making her waste places like Eden, and changing her dry land into the garden of the Lord; joy and delight will be there, praise and the sound of melody.", "geneva": "Surely the Lord shall comfort Zion: he shall comfort all her desolations, and he shall make her desert like Eden, and her wildernes like the garden of the Lord: ioy and gladnesse shalbe founde therein: praise, and the voyce of singing.", "wycliffe": "Therfor the Lord schal coumforte Sion, and he schal coumforte alle the fallyngis therof; and he schal sette the desert therof as delices, and the wildirnesse therof as a gardyn of the Lord; ioie and gladnesse schal be foundun therynne, the doyng of thankyngis and the vois of heriyng.", "rotherham": "For Yahweh hath comforted Zion, He hath comforted all her waste places, And hath made her wilderness like Eden, And her waste plain like the garden of Yahweh,—Joy and gladness, shall be found in her, Thanksgiving, and the voice of melody.", "darby": "For Jehovah shall comfort Zion, he shall comfort all her waste places; and he will make her wilderness like Eden, and her desert like the garden of Jehovah: gladness and joy shall be found therein, thanksgiving, and the voice of song.", "twenty": "", "jps": "For HaShem hath comforted Zion; He hath comforted all her waste places, and hath made her wilderness like Eden, and her desert like the garden of HaShem; joy and gladness shall be found therein, thanksgiving, and the voice of melody.", "acv": "For Jehovah has comforted Zion. He has comforted all her waste places, and has made her wilderness like Eden, and her desert like the garden of Jehovah. Joy and gladness shall be found therein, thanksgiving, and the voice of melody.", "anderson": "", "haweis": "", "noyes": "Thus will Jehovah have pity upon Zion; He will have pity upon all her desolations. He will make her wilderness like Eden, Her desert like the garden of Jehovah. Joy and gladness shall be found therein; Thanksgiving, and the voice of melody.", "webster": "For the LORD will comfort Zion: he will comfort all her waste places; and he will make her wilderness like Eden, and her desert like the garden of the LORD; joy and gladness shall be found therein, thanksgiving, and the voice of melody.", "vulgate": "consolabitur ergo Dominus et Sion consolabitur omnes ruinas eius et ponet desertum eius quasi delicias et solitudinem eius quasi hortum Domini gaudium et laetitia invenietur in ea gratiarum actio et vox laudis;", "brenton": "And now I will comfort thee, O Sion: and I have comforted all her desert places; and I will make her desert places as a garden, and her western places as the garden of the Lord; they shall find in her gladness and exultation, thanksgiving and the voice of praise."}}, {"v": 4, "ref": "51:4", "o": "הַקְשִׁ֤יבוּ אֵלַ/י֙ עַמִּ֔/י וּ/לְאוּמִּ֖/י אֵלַ֣/י הַאֲזִ֑ינוּ כִּ֤י תוֹרָה֙ מֵ/אִתִּ֣/י תֵצֵ֔א וּ/מִשְׁפָּטִ֔/י לְ/א֥וֹר עַמִּ֖ים אַרְגִּֽיעַ", "en": {"kjv": "Hearken unto me, my people; and give ear unto me, O my nation: for a law shall proceed from me, and I will make my judgment to rest for a light of the people.", "web": "“Attend to me, my people; and give ear to me, my nation: for a law shall go out from me, and I will establish my justice for a light of the peoples.", "bsb": "Pay attention to Me, My people, and listen to Me, My nation; for a law will go out from Me, and My justice will become a light to the nations; I will bring it about quickly.", "asv": "Attend unto me, O my people; and give ear unto me, O my nation: for a law shall go forth from me, and I will establish my justice for a light of the peoples.", "ylt": "Attend unto Me, O My people, And, O My nation, unto Me give ear. For a law from Me goeth out, And My judgment to the light, Peoples I do cause to rest.", "dra": "Hearken unto me, O my people, and give ear to me, O my tribes: for a law shall go forth from me, and my judgment shall rest to be a light of the nations.", "bbe": "Give attention to me, O my people; and give ear to me, O my nation; for teaching will go out from me, and the knowledge of the true God will be a light to the peoples.", "geneva": "Hearken ye vnto me, my people, and giue eare vnto me, O my people: for a Law shall proceede from me, and I will bring foorth my iudgement for the light of the people.", "wycliffe": "Mi puple, take ye heede to me, and, my lynage, here ye me; for whi a lawe schal go out fro me, and my doom schal reste in to the liyt of puplis.", "rotherham": "Attend unto me, O my people, And, O, my nation unto me give ear,—For, instruction, from me, shall go forth, And, my justice—for a light of peoples, will I establish:", "darby": "Listen unto me, my people; and give ear unto me, my nation: for a law shall proceed from me, and I will establish my judgment for a light of the peoples.", "twenty": "", "jps": "Attend unto Me, O My people, and give ear unto Me, O My nation; for instruction shall go forth from Me, and My right on a sudden for a light of the peoples.", "acv": "Attend to me, O my people, and give ear to me, O my nation. For a law shall go forth from me, and I will establish my justice for a light of the peoples.", "anderson": "", "haweis": "", "noyes": "Hearken to me, O my people! And give ear to me, O my nation! For a law shall proceed from me, And I will establish my statutes for the light of the nations.", "webster": "Hearken to me, my people; and give ear to me, O my nation: for a law shall proceed from me, and I will make my judgment to rest for a light of the people.", "vulgate": "adtendite ad me populus meus et tribus mea me audite quia lex a me exiet et iudicium meum in lucem populorum requiescet;", "brenton": "Hear me, hear me, my people; and ye kings, hearken to me: for a law shall proceed from me, and my judgment shall be for a light of the nations."}}, {"v": 5, "ref": "51:5", "o": "קָר֤וֹב צִדְקִ/י֙ יָצָ֣א יִשְׁעִ֔/י וּ/זְרֹעַ֖/י עַמִּ֣ים יִשְׁפֹּ֑טוּ אֵלַ/י֙ אִיִּ֣ים יְקַוּ֔וּ וְ/אֶל זְרֹעִ֖/י יְיַחֵלֽוּ/ן", "en": {"kjv": "My righteousness is near; my salvation is gone forth, and mine arms shall judge the people; the isles shall wait upon me, and on mine arm shall they trust.", "web": "My righteousness is near, my salvation has gone out, and my arms shall judge the peoples; the islands shall wait for me, and on my arm shall they trust.", "bsb": "My righteousness draws near, My salvation is on the way, and My arms will bring justice to the nations. The islands will look for Me and wait in hope for My arm.", "asv": "My righteousness is near, my salvation is gone forth, and mine arms shall judge the peoples; the isles shall wait for me, and on mine arm shall they trust.", "ylt": "Near is My righteousness, Gone out hath My salvation and Mine arms, Peoples they judge, on Me isles do wait, Yea, on Mine arm they do wait with hope.", "dra": "My just one is near at hand, my saviour is gone forth, and my arms shall judge the people: the islands shall look for me, and shall patiently wait for my arm.", "bbe": "Suddenly will my righteousness come near, and my salvation will be shining out like the light; the sea-lands will be waiting for me, and they will put their hope in my strong arm.", "geneva": "My righteousnes is neere: my saluation goeth foorth, and mine armes shall iudge the people: the yles shall waite for me, and shall trust vnto mine arme.", "wycliffe": "My iust man is nyy, my sauyour is gon out, and myn armes schulen deme puplis; ilis schulen abide me, and schulen suffre myn arm.", "rotherham": "At hand is my righteousness. Gone forth hath my salvation, And, mine own arms, unto the peoples, shall give justice,—Upon me, Coastlands, shall wait, And for mine arm, shall they hope.", "darby": "My righteousness is near, my salvation is gone forth, and mine arms shall judge the peoples: the isles shall wait for me, and in mine arm shall they trust.", "twenty": "", "jps": "My favour is near, My salvation is gone forth, and Mine arms shall judge the peoples; the isles shall wait for Me, and on Mine arm shall they trust.", "acv": "My righteousness is near. My salvation has gone forth, and my arms shall judge the peoples. The isles shall wait for me, and on my arm they shall trust.", "anderson": "", "haweis": "", "noyes": "My help is near; my salvation goeth forth; My arm shall judge the nations; Distant lands shall wait for me, And in my arm shall they trust.", "webster": "My righteousness [is] near; my salvation is gone forth, and my arms shall judge the people; the isles shall wait upon me, and on my arm shall they trust.", "vulgate": "prope est iustus meus egressus est salvator meus et brachia mea populos iudicabunt me insulae expectabunt et brachium meum sustinebunt;", "brenton": "My righteousness speedily draws nigh, and my salvation shall go forth as light, and on mine arm shall the Gentiles trust: the isles shall wait for me, and on mine arm shall they trust."}}, {"v": 6, "ref": "51:6", "o": "שְׂאוּ֩ לַ/שָּׁמַ֨יִם עֵֽינֵי/כֶ֜ם וְֽ/הַבִּ֧יטוּ אֶל הָ/אָ֣רֶץ מִ/תַּ֗חַת כִּֽי שָׁמַ֜יִם כֶּ/עָשָׁ֤ן נִמְלָ֨חוּ֙ וְ/הָ/אָ֨רֶץ֙ כַּ/בֶּ֣גֶד תִּבְלֶ֔ה וְ/יֹשְׁבֶ֖י/הָ כְּמוֹ כֵ֣ן יְמוּת֑וּ/ן וִ/ישֽׁוּעָתִ/י֙ לְ/עוֹלָ֣ם תִּֽהְיֶ֔ה וְ/צִדְקָתִ֖/י לֹ֥א תֵחָֽת", "en": {"kjv": "Lift up your eyes to the heavens, and look upon the earth beneath: for the heavens shall vanish away like smoke, and the earth shall wax old like a garment, and they that dwell therein shall die in like manner: but my salvation shall be for ever, and my righteousness shall not be abolished.", "web": "Lift up your eyes to the heavens, and look on the earth beneath; for the heavens shall vanish away like smoke, and the earth shall wax old like a garment; and those who dwell therein shall die in the same way: but my salvation shall be forever, and my righteousness shall not be abolished.", "bsb": "Lift up your eyes to the heavens, and look at the earth below; for the heavens will vanish like smoke, the earth will wear out like a garment, and its people will die like gnats. But My salvation will last forever, and My righteousness will never fail.", "asv": "Lift up your eyes to the heavens, and look upon the earth beneath; for the heavens shall vanish away like smoke, and the earth shall wax old like a garment; and they that dwell therein shall die in like manner: but my salvation shall be for ever, and my righteousness shall not be abolished.", "ylt": "Lift ye up to the heavens your eyes, And look attentively unto the earth beneath, For the heavens as smoke have vanished, And the earth as a garment weareth out, And its inhabitants as gnats do die, And My salvation is to the age, And My righteousness is not broken.", "dra": "Lift up your eyes to heaven, and look down to the earth beneath: for the heavens shall vanish like smoke, and the earth shall be worn away like a garment, and the inhabitants thereof shall perish in like manner: but my salvation shall be for ever, and my justice shall not fail.", "bbe": "Let your eyes be lifted up to the heavens, and turned to the earth which is under them: for the heavens will go in flight like smoke, and the earth will become old like a coat, and its people will come to destruction like insects: but my salvation will be for ever, and my righteousness will not come to an end.", "geneva": "Lift vp your eyes to the heauens, and looke vpon the earth beneath: for the heauens shall vanish away like smoke, and the earth shall waxe olde like a garment, and they that dwell therein, shall perish in like maner: but my saluation shall be for euer, and my righteousnesse shall not bee abolished.", "wycliffe": "Reise youre iyen to heuene, and se ye vndur erthe bynethe; for whi heuenes schulen melte awei as smoke, and the erthe schal be al to-brokun as a cloth, and the dwelleris therof schulen perische as these thingis; but myn helthe schal be withouten ende, and my riytfulnesse schal not fayle.", "rotherham": "Lift up—to the heavens—your eyes, And look around to the earth beneath Though, the heavens, like smoke, should have vanished And, the earth, like a garment, should fall to pieces, And, her inhabitants, in like manner, should die, Yet, my salvation, unto times age-abiding, shall continue, And, my righteousness, shall not be broken down.", "darby": "Lift up your eyes to the heavens, and look on the earth beneath: for the heavens shall vanish away like smoke, and the earth shall grow old like a garment, and they that dwell therein shall die in like manner; but my salvation shall be for ever, and my righteousness shall not be abolished.", "twenty": "", "jps": "Lift up your eyes to the heavens, and look upon the earth beneath; for the heavens shall vanish away like smoke, and the earth shall wax old like a garment, and they that dwell therein shall die in like manner; but My salvation shall be for ever, and My favour shall not be abolished.", "acv": "Lift up your eyes to the heavens, and look upon the earth beneath. For the heavens shall vanish away like smoke, and the earth shall grow old like a garment, and those who dwell in it shall die in like manner. But my salvation shall be forever, and my righteousness shall not be abolished.", "anderson": "", "haweis": "", "noyes": "Lift up your eyes to the heavens, And look down upon the earth beneath! For the heavens shall vanish away like smoke, And the earth shall decay like a garment, And its inhabitants shall perish like flies. But my salvation shall endure forever, And my goodness shall not decay.", "webster": "Lift up your eyes to the heavens, and look upon the earth beneath: for the heavens shall vanish away like smoke, and the earth shall become old like a garment, and its inhabitants shall die in like manner: but my salvation shall be for ever, and my righteousness shall not be abolished.", "vulgate": "levate in caelum oculos vestros et videte sub terra deorsum quia caeli sicut fumus liquescent et terra sicut vestimentum adteretur et habitatores eius sicut haec interibunt salus autem mea in sempiternum erit et iustitia mea non deficiet;", "brenton": "Lift up your eyes to the sky, and look on the earth beneath: for the sky was darkened like smoke, and the earth shall wax old like a garment, and the inhabitants shall die in like manner: but my righteousness shall not fail."}}, {"v": 7, "ref": "51:7", "o": "שִׁמְע֤וּ אֵלַ/י֙ יֹ֣דְעֵי צֶ֔דֶק עַ֖ם תּוֹרָתִ֣/י בְ/לִבָּ֑/ם אַל תִּֽירְאוּ֙ חֶרְפַּ֣ת אֱנ֔וֹשׁ וּ/מִ/גִּדֻּפֹתָ֖/ם אַל תֵּחָֽתּוּ", "en": {"kjv": "Hearken unto me, ye that know righteousness, the people in whose heart is my law; fear ye not the reproach of men, neither be ye afraid of their revilings.", "web": "“Listen to me, you who know righteousness, the people in whose heart is my law; don’t fear the reproach of men, neither be dismayed at their insults.", "bsb": "Listen to Me, you who know what is right, you people with My law in your hearts: Do not fear the scorn of men; do not be broken by their insults.", "asv": "Hearken unto me, ye that know righteousness, the people in whose heart is my law; fear ye not the reproach of men, neither be ye dismayed at their revilings.", "ylt": "Hearken unto Me, ye who know righteousness, A people, in whose heart is My law, Fear ye not the reproach of men, And for their reviling be not affrighted,", "dra": "Hearken to me, you that know what is just, my people who have my law in your heart: fear ye not the reproach of men, and be not afraid of their blasphemies.", "bbe": "Give ear to me, you who have knowledge of righteousness, in whose heart is my law; have no fear of the evil words of men, and give no thought to their curses.", "geneva": "Hearken vnto me, ye that know righteousnesse, the people in whose heart is my Lawe. Feare ye not the reproche of men, neither be ye afraide of their rebukes.", "wycliffe": "Ye puple, that knowen the iust man, here me, my lawe is in the herte of hem; nyle ye drede the schenschipe of men, and drede ye not the blasfemyes of hem.", "rotherham": "Hearken unto me ye who discern righteousness, The people in whose heart is my law,—Do not fear the reproach of frail men, Nor at their revilings, be dismayed;", "darby": "Hearken unto me, ye that know righteousness, the people in whose heart is my law; fear not the reproach of men, and be not afraid of their revilings.", "twenty": "", "jps": "Hearken unto Me, ye that know righteousness, the people in whose heart is My law; fear ye not the taunt of men, neither be ye dismayed at their revilings.", "acv": "Hearken to me, ye who know righteousness, the people in whose heart is my law. Fear ye not the reproach of men, nor be ye dismayed at their revilings.", "anderson": "", "haweis": "", "noyes": "Hearken to me, ye that know righteousness, The people in whose heart is my law! Fear ye not the reproach of men, Nor be disheartened by their revilings!", "webster": "Hearken to me, ye that know righteousness, the people in whose heart [is] my law; fear ye not the reproach of men, neither be ye afraid of their revilings.", "vulgate": "audite me qui scitis iustum populus lex mea in corde eorum nolite timere obprobrium hominum et blasphemias eorum ne metuatis;", "brenton": "Hear me, ye that know judgment, the people in whose heart is my law: fear not the reproach of men, and be not overcome by their contempt."}}, {"v": 8, "ref": "51:8", "o": "כִּ֤י כַ/בֶּ֨גֶד֙ יֹאכְלֵ֣/ם עָ֔שׁ וְ/כַ/צֶּ֖מֶר יֹאכְלֵ֣/ם סָ֑ס וְ/צִדְקָתִ/י֙ לְ/עוֹלָ֣ם תִּֽהְיֶ֔ה וִ/ישׁוּעָתִ֖/י לְ/ד֥וֹר דּוֹרִֽים", "en": {"kjv": "For the moth shall eat them up like a garment, and the worm shall eat them like wool: but my righteousness shall be for ever, and my salvation from generation to generation.", "web": "For the moth shall eat them up like a garment, and the worm shall eat them like wool; but my righteousness shall be forever, and my salvation to all generations.”", "bsb": "For the moth will devour them like a garment, and the worm will eat them like wool. But My righteousness will last forever, My salvation through all generations.”", "asv": "For the moth shall eat them up like a garment, and the worm shall eat them like wool; but my righteousness shall be for ever, and my salvation unto all generations.", "ylt": "For as a garment eat them doth a moth, And as wool eat them doth a worm, And My righteousness is to the age, And My salvation to all generations.", "dra": "For the worm shall eat them up as a garment: and the moth shall consume them as wool: but my salvation shall be for ever, and my justice from generation to generation.", "bbe": "For like a coat they will be food for the insect, the worm will make a meal of them like wool: but my righteousness will be for ever, and my salvation to all generations.", "geneva": "For the mothe shall eate them vp like a garment, and the worme shall eate them like wool: but my righteousnesse shalbe for euer, and my saluation from generation to generation.", "wycliffe": "For whi a worm schal ete hem so as a cloth, and a mouyte schal deuoure hem so as wolle; but myn helthe schal be withouten ende, and my riytfulnesse in to generaciouns of generaciouns.", "rotherham": "For like a garment, shall they be eaten of the moth, And like wool, shall they be eaten of the larva; But, my righteousness, unto times age-abiding shall continue, And, my salvation, unto the remotest generation.", "darby": "For the moth shall eat them up like a garment, and the worm shall eat them like wool; but my righteousness shall be for ever, and my salvation from generation to generation.", "twenty": "", "jps": "For the moth shall eat them up like a garment, and the worm shall eat them like wool; but My favour shall be for ever, and My salvation unto all generations.", "acv": "For the moth shall eat them up like a garment, and the worm shall eat them like wool. But my righteousness shall be forever, and my salvation to all generations.", "anderson": "", "haweis": "", "noyes": "For the moth shall consume them like a garment, And the worm shall eat them like wool. But my goodness shall endure forever, And my salvation from generation to generation.", "webster": "For the moth shall eat them like a garment, and the worm shall eat them like wool: but my righteousness shall be for ever, and my salvation from generation to generation.", "vulgate": "sicut enim vestimentum sic comedet eos vermis et sicut lanam sic devorabit eos tinea salus autem mea in sempiternum erit et iustitia mea in generationes generationum;", "brenton": "For as a garment will be devoured by time, and as wool will be devoured by a moth, so shall they be consumed; but my righteousness shall be for ever, and my salvation for all generations."}}, {"v": 9, "ref": "51:9", "o": "עוּרִ֨י עוּרִ֤י לִבְשִׁי עֹז֙ זְר֣וֹעַ יְהוָ֔ה ע֚וּרִי כִּ֣/ימֵי קֶ֔דֶם דֹּר֖וֹת עוֹלָמִ֑ים הֲ/ל֥וֹא אַתְּ הִ֛יא הַ/מַּחְצֶ֥בֶת רַ֖הַב מְחוֹלֶ֥לֶת תַּנִּֽין", "en": {"kjv": "Awake, awake, put on strength, O arm of the Lord; awake, as in the ancient days, in the generations of old. Art thou not it that hath cut Rahab, and wounded the dragon?", "web": "Awake, awake, put on strength, arm of Yahweh; awake, as in the days of old, the generations of ancient times. Isn’t it you who cut Rahab in pieces, who pierced the monster?", "bsb": "Awake, awake, put on strength, O arm of the LORD. Wake up as in days past, as in generations of old. Was it not You who cut Rahab to pieces, who pierced through the dragon?", "asv": "Awake, awake, put on strength, O arm of Jehovah; awake, as in the days of old, the generations of ancient times. Is it not thou that didst cut Rahab in pieces, that didst pierce the monster?", "ylt": "Awake, awake, put on strength, O arm of Jehovah, Awake, as in days of old, generations of the ages, Art not Thou it that is hewing down Rahab, Piercing a dragon!", "dra": "Arise, arise, put on strength, O thou arm of the Lord, arise as in the days of old, in the ancient generations. Hast not thou struck the proud one, and wounded the dragon?", "bbe": "Awake! awake! put on strength, O arm of the Lord, awake! as in the old days, in the generations long past. Was it not by you that Rahab was cut in two, and the dragon Wounded?", "geneva": "Rise vp, rise vp, and put on strength, O arme of the Lord: rise vp as in the olde time in the generations of the worlde. Art not thou the same, that hath cutte Rahab, and wounded the dragon?", "wycliffe": "Rise thou, rise thou, arm of the Lord, be thou clothyd in strengthe; rise thou, as in elde daies, in generaciouns of worldis. Whether thou smytidist not the proude man, woundidist not the dragoun?", "rotherham": "Awake, awake put on strength, O arm of Yahweh, Awake, As in days of old, The generations of bygone ages: Art not thou that which—Hewed down Rahab, Piercing the Crocodile?", "darby": "Awake, awake, put on strength, O arm of Jehovah; awake, as in the days of old, [as in] the generations of passed ages. Is it not thou that hath hewn Rahab in pieces, [and] pierced the monster?", "twenty": "", "jps": "Awake, awake, put on strength, O arm of HaShem; awake, as in the days of old, the generations of ancient times. Art thou not it that hewed Rahab in pieces, that pierced the dragon?", "acv": "Awake, awake, put on strength, O arm of Jehovah. Awake, as in the days of old, the generations of ancient times. Is it not thou who cut Rahab in pieces, who pierced the monster?", "anderson": "", "haweis": "", "noyes": "Awake! awake! clothe thyself with strength, O arm of Jehovah! Awake, as in the ancient days, in the generations of old!", "webster": "Awake, awake, put on thy strength, O arm of the LORD; awake, as in the ancient days, in the generations of old. [Art] thou not that which hath cut Rahab, [and] wounded the dragon?", "vulgate": "consurge consurge induere fortitudinem brachium Domini consurge sicut in diebus antiquis in generationibus saeculorum numquid non tu percussisti superbum vulnerasti draconem;", "brenton": "Awake, awake, O Jerusalem, and put on the strength of thine arm; awake as in the early time, as the ancient generation."}}, {"v": 10, "ref": "51:10", "o": "הֲ/ל֤וֹא אַתְּ הִיא֙ הַ/מַּחֲרֶ֣בֶת יָ֔ם מֵ֖י תְּה֣וֹם רַבָּ֑ה הַ/שָּׂ֨מָה֙ מַֽעֲמַקֵּי יָ֔ם דֶּ֖רֶךְ לַ/עֲבֹ֥ר גְּאוּלִֽים", "en": {"kjv": "Art thou not it which hath dried the sea, the waters of the great deep; that hath made the depths of the sea a way for the ransomed to pass over?", "web": "Isn’t it you who dried up the sea, the waters of the great deep; who made the depths of the sea a way for the redeemed to pass over?", "bsb": "Was it not You who dried up the sea, the waters of the great deep, who made a road in the depths of the sea for the redeemed to cross over?", "asv": "Is it not thou that driedst up the sea, the waters of the great deep; that madest the depths of the sea a way for the redeemed to pass over?", "ylt": "Art not Thou it that is drying up a sea, Waters of a great deep? That hath made deep places of a sea A way for the passing of the redeemed?", "dra": "Hast not thou dried up the sea, the water of the mighty deep, who madest the depth of the sea a way, that the delivered might pass over?", "bbe": "Did you not make the sea dry, the waters of the great deep? did you not make the deep waters of the sea a way for the Lord's people to go through?", "geneva": "Art not thou the same, which hath dried the Sea, euen the waters of the great deepe, making the depth of the Sea a way for the redeemed to passe ouer?", "wycliffe": "Whether thou driedist not the see, the watir of the greet depthe, which settidist the depthe of the see a weie, that men `that weren delyuered, schulden passe?", "rotherham": "Art not thou that which dried up—The Sea, The waters of the mighty Deep,—That which made of the abysses of the sea a road for the passing over of the redeemed?", "darby": "Is it not thou that dried up the sea, the waters of the great deep; that made the depths of the sea a way for the redeemed to pass over?", "twenty": "", "jps": "Art thou not it that dried up the sea, the waters of the great deep; that made the depths of the sea a way for the redeemed to pass over?", "acv": "Is it not thou who dried up the sea, the waters of the great deep, who made the depths of the sea a way for the redeemed to pass over?", "anderson": "", "haweis": "", "noyes": "Art thou not the same that smote Rahab, And wounded the dragon? Art thou not the same that dried up the sea, The waters of the great deep,—That made the depths of the sea a path for the redeemed to pass through?", "webster": "[Art] thou not that which hath dried the sea, the waters of the great deep; that hath made the depths of the sea a way for the ransomed to pass over?", "vulgate": "numquid non tu siccasti mare aquam abyssi vehementis qui posuisti profundum maris viam ut transirent liberati;", "brenton": "Art thou not it that dried the sea, the water, even the abundance of the deep; that made the depths of the sea a way of passage for the delivered and redeemed?"}}, {"v": 11, "ref": "51:11", "o": "וּ/פְדוּיֵ֨י יְהוָ֜ה יְשׁוּב֗וּ/ן וּ/בָ֤אוּ צִיּוֹן֙ בְּ/רִנָּ֔ה וְ/שִׂמְחַ֥ת עוֹלָ֖ם עַל רֹאשָׁ֑/ם שָׂשׂ֤וֹן וְ/שִׂמְחָה֙ יַשִּׂיג֔וּ/ן נָ֖סוּ יָג֥וֹן וַ/אֲנָחָֽה", "en": {"kjv": "Therefore the redeemed of the Lord shall return, and come with singing unto Zion; and everlasting joy shall be upon their head: they shall obtain gladness and joy; and sorrow and mourning shall flee away.", "web": "The ransomed of Yahweh shall return, and come with singing to Zion; and everlasting joy shall be on their heads. They shall obtain gladness and joy. Sorrow and sighing shall flee away.", "bsb": "So the redeemed of the LORD will return and enter Zion with singing, crowned with everlasting joy. Gladness and joy will overtake them, and sorrow and sighing will flee.", "asv": "And the ransomed of Jehovah shall return, and come with singing unto Zion; and everlasting joy shall be upon their heads: they shall obtain gladness and joy; and sorrow and sighing shall flee away.", "ylt": "And the ransomed of Jehovah turn back, And they have come to Zion with singing, And joy age-during is on their head, Gladness and joy they attain, Fled away have sorrow and sighing,", "dra": "And now they that are redeemed by the Lord, shall return, and shall come into Sion singing praises, and joy everlasting shall be upon their heads, they shall obtain joy and gladness, sorrow and mourning shall flee away.", "bbe": "Those whom the Lord has made free will come back with songs to Zion; and on their heads will be eternal joy: delight and joy will be theirs, and sorrow and sounds of grief will be gone for ever.", "geneva": "Therefore the redeemed of the Lord shall returne, and come with ioy vnto Zion, and euerlasting ioy shalbe vpon their head: they shall obtaine ioy, and gladnesse: and sorow and mourning shall flee away.", "wycliffe": "And now thei that ben ayenbouyt of the Lord schulen turne ayen, and schulen come heriynge in to Syon, and euerlastynge gladnesse on the heedis of hem; thei schulen holde ioie and gladnesse, sorewe and weilyng schal fle awei.", "rotherham": "Therefore, the ransomed of Yahweh, shall again come unto Zion, with shouts of triumph, With gladness age-abiding on their head,—Joy, and gladness, shall overtake [them] . Sorrow and sighing have fled away.", "darby": "So the ransomed of Jehovah shall return, and come to Zion with singing; and everlasting joy shall be upon their heads: they shall obtain gladness and joy; sorrow and sighing shall flee away.", "twenty": "", "jps": "And the ransomed of HaShem shall return, and come with singing unto Zion, and everlasting joy shall be upon their heads; they shall obtain gladness and joy, and sorrow and sighing shall flee away.", "acv": "And the ransomed of Jehovah shall return, and come with singing to Zion, and everlasting joy shall be upon their heads. They shall obtain gladness and joy, and sorrow and sighing shall flee away.", "anderson": "", "haweis": "", "noyes": "Thus shall the ransomed of Jehovah return; They shall come to Zion with singing; Everlasting joy shall be upon their heads; They shall obtain gladness and joy, And sorrow and sighing shall flee away.", "webster": "Therefore the redeemed of the LORD shall return, and come with singing to Zion; and everlasting joy [shall be] upon their head: they shall obtain gladness and joy; sorrow and mourning shall flee away.", "vulgate": "et nunc qui redempti sunt a Domino revertentur et venient in Sion laudantes et laetitia sempiterna super capita eorum gaudium et laetitiam tenebunt fugiet dolor et gemitus;", "brenton": "for by the help of the Lord they shall return, and come to Sion with joy and everlasting exultation, for praise and joy shall come upon their head: pain, and grief, and groaning, have fled away."}}, {"v": 12, "ref": "51:12", "o": "אָנֹכִ֧י אָנֹכִ֛י ה֖וּא מְנַחֶמְ/כֶ֑ם מִֽי אַ֤תְּ וַ/תִּֽירְאִי֙ מֵ/אֱנ֣וֹשׁ יָמ֔וּת וּ/מִ/בֶּן אָדָ֖ם חָצִ֥יר יִנָּתֵֽן", "en": {"kjv": "I, even I, am he that comforteth you: who art thou, that thou shouldest be afraid of a man that shall die, and of the son of man which shall be made as grass;", "web": "“I, even I, am he who comforts you: who are you, that you are afraid of man who shall die, and of the son of man who shall be made as grass;", "bsb": "“I, even I, am He who comforts you. Why should you be afraid of mortal man, of a son of man who withers like grass?", "asv": "I, even I, am he that comforteth you: who art thou, that thou art afraid of man that shall die, and of the son of man that shall be made as grass;", "ylt": "I--I am He--your comforter, Who art thou--and thou art afraid of man? he dieth! And of the son of man--grass he is made!", "dra": "I myself will comfort you: who art thou, that thou shouldst be afraid of a mortal man, and of the son of man, who shall wither away like grass?", "bbe": "I, even I, am your comforter: are you so poor in heart as to be in fear of man who will come to an end, and of the son of man who will be like grass?", "geneva": "I, euen I am he, that comfort you. Who art thou, that thou shouldest feare a mortall man, and the sonne of man, which shalbe made as grasse?", "wycliffe": "`Y my silf schal coumforte you; what art thou, that thou drede of a deedli man, and of the sone of man, that schal wexe drie so as hei?", "rotherham": "I—I, am he that comforteth you,—Who art, thou, that thou hast feared Frail man that dieth, and A son of the earthborn, who, as grass, shall be delivered up?", "darby": "I, [even] I, am he that comforteth you: who art thou, that thou fearest a man that shall die, and the son of man that shall become as grass;", "twenty": "", "jps": "I, even I, am He that comforteth you: who art thou, that thou art afraid of man that shall die, and of the son of man that shall be made as grass;", "acv": "I, even I, am he who comforts you. Who are thou, that thou are afraid of man who shall die, and of the son of man who shall be made as grass,", "anderson": "", "haweis": "", "noyes": "I, even I, am he that hath pity upon you; Who art thou, that thou art afraid of man, that shall die, Of the son of man, that shall perish like grass,", "webster": "I, [even] I, [am] he that comforteth you: who [art] thou, that thou shouldest be afraid of a man [that] shall die, and of the son of man [who] shall be made [as] grass;", "vulgate": "ego ego ipse consolabor vos quis tu ut timeres ab homine mortali et a filio hominis qui quasi faenum ita arescet;", "brenton": "I, even I, am he that comforts thee: consider who thou art, that thou wast afraid of mortal man, and of the son of man, who are withered as grass."}}, {"v": 13, "ref": "51:13", "o": "וַ/תִּשְׁכַּ֞ח יְהוָ֣ה עֹשֶׂ֗/ךָ נוֹטֶ֣ה שָׁמַיִם֮ וְ/יֹסֵ֣ד אָרֶץ֒ וַ/תְּפַחֵ֨ד תָּמִ֜יד כָּל הַ/יּ֗וֹם מִ/פְּנֵי֙ חֲמַ֣ת הַ/מֵּצִ֔יק כַּ/אֲשֶׁ֥ר כּוֹנֵ֖ן לְ/הַשְׁחִ֑ית וְ/אַיֵּ֖ה חֲמַ֥ת הַ/מֵּצִֽיק", "en": {"kjv": "And forgettest the Lord thy maker, that hath stretched forth the heavens, and laid the foundations of the earth; and hast feared continually every day because of the fury of the oppressor, as if he were ready to destroy? and where is the fury of the oppressor?", "web": "and have forgotten Yahweh your Maker, who stretched out the heavens, and laid the foundations of the earth; and fear continually all the day because of the fury of the oppressor, when he makes ready to destroy? and where is the fury of the oppressor?", "bsb": "But you have forgotten the LORD, your Maker, who stretched out the heavens and laid the foundations of the earth. You live in terror all day long because of the fury of the oppressor who is bent on destruction. But where is the fury of the oppressor?", "asv": "and hast forgotten Jehovah thy Maker, that stretched forth the heavens, and laid the foundations of the earth; and fearest continually all the day because of the fury of the oppressor, when he maketh ready to destroy? and where is the fury of the oppressor?", "ylt": "And thou dost forget Jehovah thy maker, Who is stretching out the heavens, and founding earth, And thou dost fear continually all the day, Because of the fury of the oppressor, As he hath prepared to destroy. And where is the fury of the oppressor?", "dra": "And thou hast forgotten the Lord thy maker, who stretched out the heavens, and founded the earth: and thou hast been afraid continually all the day at the presence of his fury who afflicted thee, and had prepared himself to destroy thee: where is now the fury of the oppressor?", "bbe": "And you have given no thought to the Lord your Maker, by whom the heavens were stretched out, and the earth placed on its base; and you went all day in fear of the wrath of the cruel one, when he was making ready for your destruction. And where is the wrath of the cruel one?", "geneva": "And forgettest the Lord thy maker, that hath spred out the heauens, and layde the foundations of the earth? and hast feared continually all the day, because of the rage of the oppressour, which is readie to destroy? Where is now the rage of the oppressour?", "wycliffe": "And thou hast foryete `the Lord, thi creatour, that stretchide abrood heuenes, and foundide the erthe; and thou dreddist contynueli al dai of the face of his woodnesse, that dide tribulacioun to thee, and made redi for to leese. Where is now the woodnesse of the troblere?", "rotherham": "That thou hast forgotten Yahweh thy maker, Who stretched out the heavens And founded the earth? That thou hast dreaded continually, all the day, by reason of the fury of the oppressor, in that he was ready to destroy? Where then is the fury of the oppressor?", "darby": "and forgettest Jehovah thy Maker, who hath stretched out the heavens, and laid the foundations of the earth; and thou art afraid continually all the day because of the fury of the oppressor, when he prepareth to destroy? And where is the fury of the oppressor?", "twenty": "", "jps": "And hast forgotten HaShem thy Maker, that stretched forth the heavens, and laid the foundations of the earth; and fearest continually all the day because of the fury of the oppressor, as he maketh ready to destroy? And where is the fury of the oppressor?", "acv": "and have forgotten Jehovah thy maker, who stretched forth the heavens, and laid the foundations of the earth, and fear continually all the day because of the fury of the oppressor, when he makes ready to destroy? And where is the fury of the oppressor?", "anderson": "", "haweis": "", "noyes": "And forgettest Jehovah thy maker, That stretched out the heavens, And founded the earth, And fearest continually every day, On account of the fury of the oppressor, As if he were taking aim to destroy thee? Where now is the fury of the oppressor?", "webster": "And forgettest the LORD thy maker, that hath stretched forth the heavens, and laid the foundations of the earth; and hast feared continually every day because of the fury of the oppressor, as if he were ready to destroy? and where [is] the fury of the oppressor?", "vulgate": "et oblitus es Domini factoris tui qui tetendit caelos et fundavit terram et formidasti iugiter tota die a facie furoris eius qui te tribulabat et paraverat ad perdendum ubi nunc est furor tribulantis;", "brenton": "And thou hast forgotten God who made thee, who made the sky and founded the earth; and thou wert continually afraid because of the wrath of him that afflicted thee: for whereas he counselled to take thee away, yet now where is the wrath of him that afflicted thee?"}}, {"v": 14, "ref": "51:14", "o": "מִהַ֥ר צֹעֶ֖ה לְ/הִפָּתֵ֑חַ וְ/לֹא יָמ֣וּת לַ/שַּׁ֔חַת וְ/לֹ֥א יֶחְסַ֖ר לַחְמֽ/וֹ", "en": {"kjv": "The captive exile hasteneth that he may be loosed, and that he should not die in the pit, nor that his bread should fail.", "web": "The captive exile shall speedily be freed; and he shall not die and go down into the pit, neither shall his bread fail.", "bsb": "The captive will soon be freed; he will not die in the dungeon, and his bread will not be lacking.", "asv": "The captive exile shall speedily be loosed; and he shall not die and go down into the pit, neither shall his bread fail.", "ylt": "Hastened hath a wanderer to be loosed, And he doth not die at the pit, And his bread is not lacking.", "dra": "He shall quickly come that is going to open unto you, and he shall not kill unto utter destruction, neither shall his bread fail.", "bbe": "The prisoner, bent under his chain, will quickly be made free, and will not go down into the underworld, and his bread will not come to an end.", "geneva": "The captiue hasteneth to be loosed, and that hee should not die in the pitte, nor that his bread should faile.", "wycliffe": "Soone he schal come, goynge for to opene; and he schal not sle til to deth, nether his breed schal faile.", "rotherham": "The captive hath hastened to be loosed,—That he might not die in the pit. Neither should, his bread, be cut off.", "darby": "He that is bowed down shall speedily be loosed, and he shall not die in the pit, nor shall his bread fail.", "twenty": "", "jps": "He that is bent down shall speedily be loosed; and he shall not go down dying into the pit, neither shall his bread fail.", "acv": "The captive exile shall speedily be loosed, and he shall not die in the pit, nor shall his bread fail.", "anderson": "", "haweis": "", "noyes": "Soon shall the enchained be loosed; He shall not die in the pit, Nor shall his bread fail.", "webster": "The captive exile hasteneth that he may be loosed, and that he should not die in the pit, nor that his bread should fail.", "vulgate": "cito veniet gradiens ad aperiendum et non interficiet usque ad internicionem nec deficiet panis eius;", "brenton": "For in thy deliverance he shall not halt, nor tarry;"}}, {"v": 15, "ref": "51:15", "o": "וְ/אָֽנֹכִי֙ יְהוָ֣ה אֱלֹהֶ֔י/ךָ רֹגַ֣ע הַ/יָּ֔ם וַ/יֶּהֱמ֖וּ גַּלָּ֑י/ו יְהוָ֥ה צְבָא֖וֹת שְׁמֽ/וֹ", "en": {"kjv": "But I am the Lord thy God, that divided the sea, whose waves roared: The Lord of hosts is his name.", "web": "For I am Yahweh your God, who stirs up the sea, so that its waves roar: Yahweh of Armies is his name.", "bsb": "For I am the LORD your God who stirs up the sea so that its waves roar— the LORD of Hosts is His name.", "asv": "For I am Jehovah thy God, who stirreth up the sea, so that the waves thereof roar: Jehovah of hosts is his name.", "ylt": "And I am Jehovah thy God, Quieting the sea, when its billows roar, Jehovah of Hosts is His name.", "dra": "But I am the Lord thy God, who trouble the sea, and the waves thereof swell: the Lord of hosts is my name.", "bbe": "For I am the Lord your God, who makes the sea calm when its waves are thundering: the Lord of armies is his name.", "geneva": "And I am the Lord thy God that deuided the Sea, when his waues roared: the Lord of hostes is his Name.", "wycliffe": "Forsothe Y am thi Lord God, that disturble the see, and the wawis therof wexen greet; the Lord of oostis is my name.", "rotherham": "But, I—Yahweh, am thy God, Who threw into commotion the sea And the waves thereof roared,—Yahweh of hosts, is his name.", "darby": "And I am Jehovah thyGod, who raiseth the sea, so that its waves roar: Jehovah of hosts is his name.", "twenty": "", "jps": "For I am HaShem thy G-d, who stirreth up the sea, that the waves thereof roar; HaShem of hosts is His name.", "acv": "For I am Jehovah thy God, who stirs up the sea so that the waves of it roar. Jehovah of hosts is his name.", "anderson": "", "haweis": "", "noyes": "For I am Jehovah thy God, That rebuketh the sea when his waves roar; Jehovah of hosts is his name.", "webster": "But I [am] the LORD thy God, that divided the sea, whose waves roared: The LORD of hosts [is] his name.", "vulgate": "ego autem sum Dominus Deus tuus qui conturbo mare et intumescunt fluctus eius Dominus exercituum nomen meum;", "brenton": "for I am thy God, that troubles the sea, and causes the waves thereof to roar: the Lord of hosts is my name."}}, {"v": 16, "ref": "51:16", "o": "וָ/אָשִׂ֤ים דְּבָרַ/י֙ בְּ/פִ֔י/ךָ וּ/בְ/צֵ֥ל יָדִ֖/י כִּסִּיתִ֑י/ךָ לִ/נְטֹ֤עַ שָׁמַ֨יִם֙ וְ/לִ/יסֹ֣ד אָ֔רֶץ וְ/לֵ/אמֹ֥ר לְ/צִיּ֖וֹן עַמִּ/י אָֽתָּה", "en": {"kjv": "And I have put my words in thy mouth, and I have covered thee in the shadow of mine hand, that I may plant the heavens, and lay the foundations of the earth, and say unto Zion, Thou art my people.", "web": "I have put my words in your mouth, and have covered you in the shadow of my hand, that I may plant the heavens, and lay the foundations of the earth, and tell Zion, ‘You are my people.’”", "bsb": "I have put My words in your mouth, and covered you with the shadow of My hand, to establish the heavens, to found the earth, and to say to Zion, ‘You are My people.’”", "asv": "And I have put my words in thy mouth, and have covered thee in the shadow of my hand, that I may plant the heavens, and lay the foundations of the earth, and say unto Zion, Thou art my people.", "ylt": "And I put My words in thy mouth, And with the shadow of My hand have covered thee, To plant the heavens, and to found earth, And to say to Zion, `My people art thou.'", "dra": "I have put my words in thy mouth, and have protected thee in the shadow of my hand, that thou mightest plant the heavens, and found the earth: and mightest say to Sion: Thou art my people.", "bbe": "And I have put my words in your mouth, covering you with the shade of my hand, stretching out the heavens, and placing the earth on its base, and saying to Zion, You are my people.", "geneva": "And I haue put my wordes in thy mouth, and haue defended thee in the shadowe of mine hand, that I may plant the heauens, and lay the foundation of the earth, and say vnto Zion, Thou art my people.", "wycliffe": "Y haue put my wordis in thi mouth, and Y defendide thee in the schadewe of myn hond; that thou plaunte heuenes, and founde the erthe, and seie to Sion, Thou art my puple.", "rotherham": "Therefore have I put my words in thy mouth, And with the shadow of my hand, have I covered thee,—To plant the heavens, and To lay the foundations of the earth, and To say unto Zion My people, thou art!", "darby": "And I have put my words in thy mouth, and covered thee with the shadow of my hand, to plant the heavens, and to lay the foundations of the earth, and to say unto Zion, Thou art my people.", "twenty": "", "jps": "And I have put My words in thy mouth, and have covered thee in the shadow of My hand, that I may plant the heavens, and lay the foundations of the earth, and say unto Zion: 'Thou art My people.'", "acv": "And I have put my words in thy mouth, and have covered thee in the shadow of my hand, that I may plant the heavens, and lay the foundations of the earth, and say to Zion, Thou are my people.", "anderson": "", "haweis": "", "noyes": "I have put my words into thy mouth, And have covered thee with the shadow of my hand, To establish the heavens, and to found the earth. And to say to Zion, \"Thou art my people!\"", "webster": "And I have put my words in thy mouth, and have covered thee in the shade of my hand, that I may plant the heavens, and lay the foundations of the earth, and say to Zion, Thou [art] my people.", "vulgate": "posui verba mea in ore tuo et in umbra manus meae protexi te ut plantes caelos et fundes terram et dicas ad Sion populus meus es tu;", "brenton": "I will put my words into thy mouth, and I will shelter thee under the shadow of mine hand, with which I fixed the sky, and founded the earth: and the Lord shall say to Sion, Thou art my people."}}, {"v": 17, "ref": "51:17", "o": "הִתְעוֹרְרִ֣י הִֽתְעוֹרְרִ֗י ק֚וּמִי יְר֣וּשָׁלִַ֔ם אֲשֶׁ֥ר שָׁתִ֛ית מִ/יַּ֥ד יְהוָ֖ה אֶת כּ֣וֹס חֲמָת֑/וֹ אֶת קֻבַּ֜עַת כּ֧וֹס הַ/תַּרְעֵלָ֛ה שָׁתִ֖ית מָצִֽית", "en": {"kjv": "Awake, awake, stand up, O Jerusalem, which hast drunk at the hand of the Lord the cup of his fury; thou hast drunken the dregs of the cup of trembling, and wrung them out.", "web": "Awake, awake, stand up, Jerusalem, that have drunk at the hand of Yahweh the cup of his wrath; you have drunken the bowl of the cup of staggering, and drained it.", "bsb": "Awake, awake! Rise up, O Jerusalem, you who have drunk from the hand of the LORD the cup of His fury; you who have drained the goblet to the dregs— the cup that makes men stagger.", "asv": "Awake, awake, stand up, O Jerusalem, that hast drunk at the hand of Jehovah the cup of his wrath; thou hast drunken the bowl of the cup of staggering, and drained it.", "ylt": "Stir thyself, stir thyself, rise, Jerusalem, Who hast drunk from the hand of Jehovah The cup of His fury, The goblet, the cup of trembling, thou hast drunk, Thou hast wrung out.", "dra": "Arise, arise, stand up, O Jerusalem, which hast drunk at the hand of the Lord the cup of his wrath; thou hast drunk even to the bottom of the cup of dead sleep, and thou hast drunk even to the dregs.", "bbe": "Awake! awake! up! O Jerusalem, you who have taken from the Lord's hand the cup of his wrath; tasting in full measure the wine which overcomes.", "geneva": "Awake, awake, and stande vp, O Ierusalem, which hast drunke at the hande of the Lord the cup of his wrath: thou hast drunken the dregges of the cup of trembling, and wrung them out.", "wycliffe": "Be thou reisid, be thou reisid, rise thou, Jerusalem, that hast drunke of the hond of the Lord the cuppe of his wraththe; thou hast drunke `til to the botme of the cuppe of sleep, thou hast drunke of `til to the drastis.", "rotherham": "Rouse thee—rouse, thee stand up, O Jerusalem, Who hast drunk, at the hand of Yahweh, his cup of indignation: The goblet-cup of confusion, hast thou drunk—hast thou drained.", "darby": "Arouse thyself, arouse thyself, stand up, Jerusalem, which hast drunk at the hand of Jehovah the cup of his fury. Thou hast drunk, hast drained out the goblet-cup of bewilderment:", "twenty": "", "jps": "Awake, awake, stand up, O Jerusalem, that hast drunk at the hand of HaShem the cup of His fury; thou hast drunken the beaker, even the cup of staggering, and drained it.", "acv": "Awake, awake, stand up, O Jerusalem, who have drunk at the hand of Jehovah the cup of his wrath. Thou have drunk the bowl of the cup of staggering, and drained it.", "anderson": "", "haweis": "", "noyes": "Awake, awake, stand up, O Jerusalem! Thou that hast drunk from the hand of Jehovah the cup of his fury, Thou that hast drunk to the dregs the cup of giddiness!", "webster": "Awake, awake, stand up, O Jerusalem, which hast drank at the hand of the LORD the cup of his fury; thou hast drank the dregs of the cup of trembling, [and] wrung [them] out.", "vulgate": "elevare elevare consurge Hierusalem quae bibisti de manu Domini calicem irae eius usque ad fundum calicis soporis bibisti et epotasti usque ad feces;", "brenton": "Awake, awake, stand up, O Jerusalem, that hast drunk at the hand of the Lord the cup of his fury: for thou hast drunk out and drained the cup of calamity, the cup of wrath:"}}, {"v": 18, "ref": "51:18", "o": "אֵין מְנַהֵ֣ל לָ֔/הּ מִ/כָּל בָּנִ֖ים יָלָ֑דָה וְ/אֵ֤ין מַחֲזִיק֙ בְּ/יָדָ֔/הּ מִ/כָּל בָּנִ֖ים גִּדֵּֽלָה", "en": {"kjv": "There is none to guide her among all the sons whom she hath brought forth; neither is there any that taketh her by the hand of all the sons that she hath brought up.", "web": "There is no one to guide her among all the sons to whom she has given birth; neither is there any who takes her by the hand among all the sons who she has brought up.", "bsb": "Among all the sons she bore, there is no one to guide her; among all the sons she brought up, there is no one to take her hand.", "asv": "There is none to guide her among all the sons whom she hath brought forth; neither is there any that taketh her by the hand among all the sons that she hath brought up.", "ylt": "There is not a leader to her Out of all the sons she hath borne, And there is none laying hold on her hand Out of all the sons she hath nourished.", "dra": "There is none that can uphold her among all the children that she hath brought forth: and there is none that taketh her by the hand among all the children that she hath brought up.", "bbe": "She has no one among all her children to be her guide; not one of the sons she has taken care of takes her by the hand.", "geneva": "There is none to guide her among all the sonnes, whome she hath brought foorth: there is none that taketh her by the hand of all the sonnes that she hath brought vp.", "wycliffe": "Noon is that susteyneth it, of alle the sones whiche it gendride; and noon is that takith the hond therof, of alle the sones whiche it nurshide.", "rotherham": "There is none to guide her, Among all the sons she hath borne,—There is none to grasp her hand, Among all the sons she hath brought up.", "darby": "— there is none to guide her among all the children that she hath brought forth; neither is there any to take her by the hand of all the children that she hath brought up.", "twenty": "", "jps": "There is none to guide her among all the sons whom she hath brought forth; neither is there any that taketh her by the hand of all the sons that she hath brought up.", "acv": "There is none to guide her among all the sons whom she has brought forth, nor is there any who takes her by the hand among all the sons that she has brought up.", "anderson": "", "haweis": "", "noyes": "There is not one to lead her, of all the sons which she hath brought forth, Nor is there one to take her by the hand, of all the sons which she hath nurtured.", "webster": "[There is] none to guide her among all the sons [whom] she hath brought forth; neither [is there any] that taketh her by the hand of all the sons [that] she hath brought up.", "vulgate": "non est qui sustentet eam ex omnibus filiis quos genuit et non est qui adprehendat manum eius ex omnibus filiis quos enutrivit;", "brenton": "and there was none to comfort thee of all the children whom thou borest; and there was none to take hold of thine hand, not even of all the children whom thou has reared."}}, {"v": 19, "ref": "51:19", "o": "שְׁתַּ֤יִם הֵ֨נָּה֙ קֹֽרְאֹתַ֔יִ/ךְ מִ֖י יָנ֣וּד לָ֑/ךְ הַ/שֹּׁ֧ד וְ/הַ/שֶּׁ֛בֶר וְ/הָ/רָעָ֥ב וְ/הַ/חֶ֖רֶב מִ֥י אֲנַחֲמֵֽ/ךְ", "en": {"kjv": "These two things are come unto thee; who shall be sorry for thee? desolation, and destruction, and the famine, and the sword: by whom shall I comfort thee?", "web": "These two things have happened to you. Who will bemoan you? Desolation and destruction, and the famine and the sword; how shall I comfort you?", "bsb": "These pairs have befallen you: devastation and destruction, famine and sword. Who will grieve for you? Who can comfort you?", "asv": "These two things are befallen thee, who shall bemoan thee? desolation and destruction, and the famine and the sword; how shall I comfort thee?", "ylt": "These two are meeting thee, who is moved for thee? Spoiling and destruction--Famine and sword, who--I comfort thee?", "dra": "There are two things that have happened to thee: who shall be sorry for thee? desolation, and destruction, and the famine, and the sword, who shall comfort thee?", "bbe": "These two things have come on you; who will be weeping for you? wasting and destruction; death from need of food, and from the sword; how may you be comforted?", "geneva": "These two thinges are come vnto thee: who will lament thee? desolation and destruction and famine, and the sworde: by whome shall I comfort thee?", "wycliffe": "Twei thingis ben that camen to thee; who schal be sori on thee? distriyng, and defoulyng, and hungur, and swerd. Who schal coumforte thee?", "rotherham": "Twain, are the things befalling thee, Who will lament for thee? Wasting and destruction and famine and sword By whom shall I comfort thee?", "darby": "These two [things] are come unto thee; who will bemoan thee? — desolation and destruction, and famine and sword: how shall I comfort thee?", "twenty": "", "jps": "These two things are befallen thee; who shall bemoan thee? desolation and destruction, and the famine and the sword; how shall I comfort thee?", "acv": "These two things have befallen thee (Who shall bemoan thee?): Desolation and destruction, and the famine and the sword. How shall I comfort thee?", "anderson": "", "haweis": "", "noyes": "These two things have come upon thee, And who bemoaneth thee? Desolation and destruction, and famine and the sword; How shall I comfort thee?", "webster": "These two [things] have come to thee; who shall be sorry for thee? desolation, and destruction, and famine, and the sword: by whom shall I comfort thee?", "vulgate": "duo sunt quae occurrerunt tibi quis contristabitur super te vastitas et contritio et fames et gladius quis consolabitur te;", "brenton": "Wherefore these things are against thee; who shall sympathize with thee in thy grief? downfall, and destruction, famine, and sword: who shall comfort thee?"}}, {"v": 20, "ref": "51:20", "o": "בָּנַ֜יִ/ךְ עֻלְּפ֥וּ שָׁכְב֛וּ בְּ/רֹ֥אשׁ כָּל חוּצ֖וֹת כְּ/ת֣וֹא מִכְמָ֑ר הַֽ/מְלֵאִ֥ים חֲמַת יְהוָ֖ה גַּעֲרַ֥ת אֱלֹהָֽיִ/ךְ", "en": {"kjv": "Thy sons have fainted, they lie at the head of all the streets, as a wild bull in a net: they are full of the fury of the Lord, the rebuke of thy God.", "web": "Your sons have fainted, they lie at the head of all the streets, as an antelope in a net; they are full of the wrath of Yahweh, the rebuke of your God.", "bsb": "Your sons have fainted; they lie at the head of every street, like an antelope in a net. They are full of the wrath of the LORD, the rebuke of your God.", "asv": "Thy sons have fainted, they lie at the head of all the streets, as an antelope in a net; they are full of the wrath of Jehovah, the rebuke of thy God.", "ylt": "Thy sons have been wrapped up, they have lain down, At the head of all out places, as a wild ox in a net, They are full of the fury of Jehovah, The rebuke of Thy God.", "dra": "Thy children are cast forth, they have slept at the head of all the ways, and the wild ox that is snared: full of the indignation of the Lord, of the rebuke of thy God.", "bbe": "Your sons are overcome, like a roe in a net; they are full of the wrath of the Lord, the punishment of your God.", "geneva": "Thy sonnes haue fainted, and lye at the head of all the streetes as a wilde bull in a nette, and are full of the wrath of the Lord, and rebuke of thy God.", "wycliffe": "Thi sones ben cast forth, thei slepten in the heed of alle weies, as the beeste orix, takun bi a snare; thei ben ful of indignacioun of the Lord, of blamyng of thi God.", "rotherham": "Thy sons, have fainted, They lie at the head of all the streets like a gazelle in a net,—Who, indeed, are full of The indignation of Yahweh The rebuke of thy God.", "darby": "Thy children have fainted, they lie at the head of all the streets, as an oryx in a net: they are full of the fury of Jehovah, the rebuke of thyGod.", "twenty": "", "jps": "Thy sons have fainted, they lie at the head of all the streets, as an antelope in a net; they are full of the fury of HaShem, the rebuke of thy G-d.", "acv": "Thy sons have fainted. They lie at the head of all the streets, as an antelope in a net. They are full of the wrath of Jehovah, the rebuke of thy God.", "anderson": "", "haweis": "", "noyes": "Thy sons have fainted; they lie at the head of all the streets, Like a deer in the net; They are full of the wrath of Jehovah, Of the rebuke of thy God.", "webster": "Thy sons have fainted, they lie at the head of all the streets, as a wild bull in a net: they are full of the fury of the LORD, the rebuke of thy God.", "vulgate": "filii tui proiecti sunt dormierunt in capite omnium viarum sicut bestia inlaqueata pleni indignatione Domini increpatione Dei tui;", "brenton": "Thy sons are the perplexed ones, that sleep at the top of every street as a half-boiled beet; they that are full of the anger of the Lord, caused to faint by the Lord God."}}, {"v": 21, "ref": "51:21", "o": "לָ/כֵ֛ן שִׁמְעִי נָ֥א זֹ֖את עֲנִיָּ֑ה וּ/שְׁכֻרַ֖ת וְ/לֹ֥א מִ/יָּֽיִן", "en": {"kjv": "Therefore hear now this, thou afflicted, and drunken, but not with wine:", "web": "Therefore hear now this, you afflicted, and drunken, but not with wine:", "bsb": "Therefore now hear this, you afflicted one, drunken, but not with wine.", "asv": "Therefore hear now this, thou afflicted, and drunken, but not with wine:", "ylt": "Therefore, hear, I pray thee, this, O afflicted and drunken one, and not with wine,", "dra": "Therefore hear this, thou poor little one, and thou that art drunk but not with wine.", "bbe": "So now give ear to this, you who are troubled and overcome, but not with wine:", "geneva": "Therefore heare nowe this, thou miserable and drunken, but not with wine.", "wycliffe": "Therfor, thou pore, and drunkun, not of wyn, here these thingis.", "rotherham": "Therefore, hear, I pray thee, this, thou humbled one,—And drunken but not with wine:—", "darby": "Therefore hear now this, thou afflicted, and drunken, but not with wine:", "twenty": "", "jps": "Therefore hear now this, thou afflicted, and drunken, but not with wine;", "acv": "Therefore hear now this, thou afflicted, and drunken, but not with wine.", "anderson": "", "haweis": "", "noyes": "Therefore, hear this, thou afflicted, Thou drunken, and not with wine!", "webster": "Therefore hear now this, thou afflicted, and drunken, but not with wine:", "vulgate": "idcirco audi hoc paupercula et ebria non a vino;", "brenton": "Therefore hear, thou afflicted one, and drunken, but not with wine;"}}, {"v": 22, "ref": "51:22", "o": "כֹּֽה אָמַ֞ר אֲדֹנַ֣יִ/ךְ יְהוָ֗ה וֵ/אלֹהַ֨יִ/ךְ֙ יָרִ֣יב עַמּ֔/וֹ הִנֵּ֥ה לָקַ֛חְתִּי מִ/יָּדֵ֖/ךְ אֶת כּ֣וֹס הַ/תַּרְעֵלָ֑ה אֶת קֻבַּ֨עַת֙ כּ֣וֹס חֲמָתִ֔/י לֹא תוֹסִ֥יפִי לִ/שְׁתּוֹתָ֖/הּ עֽוֹד", "en": {"kjv": "Thus saith thy Lord the Lord, and thy God that pleadeth the cause of his people, Behold, I have taken out of thine hand the cup of trembling, even the dregs of the cup of my fury; thou shalt no more drink it again:", "web": "Thus says your Lord Yahweh, and your God who pleads the cause of his people, “Behold, I have taken out of your hand the cup of staggering, even the bowl of the cup of my wrath; you shall no more drink it again:", "bsb": "Thus says your Lord, the LORD, even your God, who defends His people: “See, I have removed from your hand the cup of staggering. From that goblet, the cup of My fury, you will never drink again.", "asv": "Thus saith thy Lord Jehovah, and thy God that pleadeth the cause of his people, Behold, I have taken out of thy hand the cup of staggering, even the bowl of the cup of my wrath; thou shalt no more drink it again:", "ylt": "Thus said thy Lord Jehovah, and thy God, He pleadeth for his people: `Lo, I have taken out of thy hand the cup of trembling, The goblet, the cup of My fury, Thou dost not add to drink it any more.", "dra": "Thus saith thy Sovereign the Lord, and thy God, who will fight for his people: Behold I have taken out of thy hand the cup of dead sleep, the dregs of the cup of my indignation, thou shalt not drink it again any more.", "bbe": "This is the word of the Lord your master, even your God who takes up the cause of his people: See, I have taken out of your hand the cup which overcomes, even the cup of my wrath; it will not again be given to you:", "geneva": "Thus saith thy Lord God, euen God that pleadeth the cause of his people, Beholde, I haue taken out of thine hande the cuppe of trembling, euen the dregges of the cuppe of my wrath: thou shalt drinke it no more.", "wycliffe": "Thi lordli gouernour, the Lord, and thi God, that fauyt for his puple, seith these thingis, Lo! Y haue take fro thyn hond the cuppe of sleep, the botme of the cuppe of myn indignacioun; Y schal not leie to, that thou drynke it ony more.", "rotherham": "Thus, saith Thy Lord, Yahweh, Even thy God who pleadeth the cause of his people:—Lo! I have taken, out of thy hand, the cup of confusion,—As for the goblet-cup of mine indignation, Thou shalt not again drink it, any more;", "darby": "thus saith thy Lord, Jehovah, and thyGod, who pleadeth the cause of his people, Behold, I take out of thy hand the cup of bewilderment, the goblet-cup of my fury; thou shalt no more drink it again:", "twenty": "", "jps": "Thus saith thy L-rd HaShem, and thy G-d that pleadeth the cause of His people: behold, I have taken out of thy hand the cup of staggering; the beaker, even the cup of My fury, thou shalt no more drink it again;", "acv": "Thus says thy lord Jehovah, and thy God who pleads the cause of his people: Behold, I have taken out of thy hand the cup of staggering, even the bowl of the cup of my wrath. Thou shall no more drink it again.", "anderson": "", "haweis": "", "noyes": "Thus saith thy Lord, Jehovah, And thy God, that defendeth the cause of his people. Behold, I will take from thy hand the cup of giddiness, The cup of my wrath; Thou shalt drink no more of it.", "webster": "Thus saith thy Lord Jehovah, and thy God [that] pleadeth the cause of his people, Behold, I have taken out of thy hand the cup of trembling, [even] the dregs of the cup of my fury; thou shalt no more drink it again:", "vulgate": "haec dicit Dominator tuus Dominus et Deus tuus qui pugnavit pro populo suo ecce tuli de manu tua calicem soporis fundum calicis indignationis meae non adicies ut bibas illud ultra;", "brenton": "thus saith the Lord God that judges his people, Behold, I have taken out of thine hand the cup of calamity, the cup of my wrath; and thou shalt not drink it any more."}}, {"v": 23, "ref": "51:23", "o": "וְ/שַׂמְתִּ֨י/הָ֙ בְּ/יַד מוֹגַ֔יִ/ךְ אֲשֶׁר אָמְר֥וּ לְ/נַפְשֵׁ֖/ךְ שְׁחִ֣י וְ/נַעֲבֹ֑רָה וַ/תָּשִׂ֤ימִי כָ/אָ֨רֶץ֙ גֵּוֵ֔/ךְ וְ/כַ/ח֖וּץ לַ/עֹבְרִֽים", "en": {"kjv": "But I will put it into the hand of them that afflict thee; which have said to thy soul, Bow down, that we may go over: and thou hast laid thy body as the ground, and as the street, to them that went over.", "web": "and I will put it into the hand of those who afflict you, who have said to your soul, ‘Bow down, that we may walk over you;’ and you have laid your back as the ground, and as the street, to those who walk over.”", "bsb": "I will place it in the hands of your tormentors, who told you: ‘Lie down, so we can walk over you,’ so that you made your back like the ground, like a street to be traversed.”", "asv": "and I will put it into the hand of them that afflict thee, that have said to thy soul, Bow down, that we may go over; and thou hast laid thy back as the ground, and as the street, to them that go over.", "ylt": "And I have put it into the hand of those afflicting thee, Who have said to thy soul, Bow down, and we pass over, And thou makest as the earth thy body, And as the street to those passing by!'", "dra": "And I will put it in the hand of them that have oppressed thee, and have said to thy soul: Bow down, that we may go over: and thou hast laid thy body as the ground, and as a way to them that went over.", "bbe": "And I will put it into the hand of your cruel masters, and of those whose yoke has been hard on you; who have said to your soul, Down on your face! so that we may go over you: and you have given your backs like the earth, even like the street, for them to go over.", "geneva": "But I will put it into their hande that spoile thee: which haue said to thy soule, Bowe downe, that wee may goe ouer, and thou hast layde thy bodie as the grounde, and as the streete to them that went ouer.", "wycliffe": "And Y schal sette it in the hond of hem that maden thee low, and seiden to thi soule, Be thou bowid that we passe; and thou hast set thi bodi as erthe, and as a weye to hem that goen forth.", "rotherham": "But I will put it into the hand of thy tormentors, Who said to thy soul, Bow down that we may pass over,—And so thou didst place as the ground, thy back, Yea as the street to such as were passing along.", "darby": "and I will put it into the hand of them that afflict thee; who have said to thy soul, Bow down, that we may go over; and thou hast laid thy body as the ground, and as the street to them that went over.", "twenty": "", "jps": "And I will put it into the hand of them that afflict thee; that have said to thy soul: 'Bow down, that we may go over'; and thou hast laid thy back as the ground, and as the street, to them that go over.", "acv": "And I will put it into the hand of those who afflict thee, who have said to thy soul, Bow down, that we may go over, and thou have laid thy back as the ground, and as the street, to those who go over.", "anderson": "", "haweis": "", "noyes": "And I will put it into the hand of them that have afflicted thee; That have said to thee, \"Bow down, that we may pass over!\" And thou madest thy body as the ground, And as the street, to them that passed over.", "webster": "But I will put it into the hand of them that afflict thee; who have said to thy soul, Prostrate thyself, that we may go over: and thou hast laid thy body as the ground, and as the street, to them that went over.", "vulgate": "et ponam illud in manu eorum qui te humiliaverunt et dixerunt animae tuae incurvare ut transeamus et posuisti ut terram corpus tuum et quasi viam transeuntibus;", "brenton": "And I will give it into the hands of them that injured thee, and them that afflicted thee; who said to thy soul, Bow down, that we may pass over: and thou didst level thy body with the ground to them passing by without."}}]}, {"c": 52, "verses": [{"v": 1, "ref": "52:1", "o": "עוּרִ֥י עוּרִ֛י לִבְשִׁ֥י עֻזֵּ֖/ךְ צִיּ֑וֹן לִבְשִׁ֣י בִּגְדֵ֣י תִפְאַרְתֵּ֗/ךְ יְרוּשָׁלִַ֨ם֙ עִ֣יר הַ/קֹּ֔דֶשׁ כִּ֣י לֹ֥א יוֹסִ֛יף יָבֹא בָ֥/ךְ ע֖וֹד עָרֵ֥ל וְ/טָמֵֽא", "en": {"kjv": "Awake, awake; put on thy strength, O Zion; put on thy beautiful garments, O Jerusalem, the holy city: for henceforth there shall no more come into thee the uncircumcised and the unclean.", "web": "Awake, awake, put on your strength, Zion; put on your beautiful garments, Jerusalem, the holy city: for henceforth there shall no more come into you the uncircumcised and the unclean.", "bsb": "Awake, awake, clothe yourself with strength, O Zion! Put on your garments of splendor, O Jerusalem, holy city! For the uncircumcised and unclean will no longer enter you.", "asv": "Awake, awake, put on thy strength, O Zion; put on thy beautiful garments, O Jerusalem, the holy city: for henceforth there shall no more come into thee the uncircumcised and the unclean.", "ylt": "Awake, awake, put on thy strength, O Zion, Put on the garments of thy beauty, Jerusalem--the Holy City; For enter no more into thee again, Do the uncircumcised and unclean.", "dra": "Arise, arise, put on thy strength, O Sion, put on the garments of thy glory, O Jerusalem, the city of the Holy One: for henceforth the uncircumcised, and unclean shall no more pass through thee.", "bbe": "Awake! awake! put on your strength, O Zion; put on your beautiful robes, O Jerusalem, the holy town: for from now there will never again come into you the unclean and those without circumcision.", "geneva": "Aries, arise: put on thy strength, O Zion: put on thy garments of thy beautie, O Ierusalem, the holy citie: for hencefoorth there shall no more come into thee the vncircumcised and the vncleane.", "wycliffe": "Rise thou, Sion, rise thou, be thou clothid in thi strengthe; Jerusalem, the citee of the hooli, be thou clothid in the clothis of thi glorie; for a man vncircumcidid and a man vncleene schal no more leie to, that he passe by thee.", "rotherham": "Awake, awake, Put on thy strength, O Zion,—Put on thy beautiful garments, O Jerusalem—thou holy city, For there shall not again come into thee any more the uncircumcised and unclean.", "darby": "Awake, awake; put on thy strength, O Zion; put on thy beautiful garments, Jerusalem, the holy city: for henceforth there shall no more come into thee the uncircumcised and the unclean.", "twenty": "", "jps": "Awake, awake, put on thy strength, O Zion; put on thy beautiful garments, O Jerusalem, the holy city; for henceforth there shall no more come into thee the uncircumcised and the unclean.", "acv": "Awake, awake, put on thy strength, O Zion. Put on thy beautiful garments, O Jerusalem, the holy city. For henceforth there shall no more come into thee the uncircumcised and the unclean.", "anderson": "", "haweis": "", "noyes": "Awake, awake, put on thy majesty, O Zion! Put on thy beautiful garments, O Jerusalem, the holy city! For no more shall come into thee the uncircumcised and the unclean.", "webster": "Awake, awake, put on thy strength, O Zion; put on thy beautiful garments, O Jerusalem, the holy city: for henceforth there shall no more come into thee the uncircumcised and the unclean.", "vulgate": "consurge consurge induere fortitudine tua Sion induere vestimentis gloriae tuae Hierusalem civitas sancti quia non adiciet ultra ut pertranseat per te incircumcisus et inmundus;", "brenton": "Awake, awake, Sion; put on thy strength, O Sion; and o thou put on thy glory, Jerusalem the holy city: there shall no more pass through thee, the uncircumcised and unclean."}}, {"v": 2, "ref": "52:2", "o": "הִתְנַעֲרִ֧י מֵ/עָפָ֛ר ק֥וּמִי שְּׁבִ֖י יְרֽוּשָׁלִָ֑ם התפתחו הִֽתְפַּתְּחִי֙ מוֹסְרֵ֣י צַוָּארֵ֔/ךְ שְׁבִיָּ֖ה בַּת צִיּֽוֹן", "en": {"kjv": "Shake thyself from the dust; arise, and sit down, O Jerusalem: loose thyself from the bands of thy neck, O captive daughter of Zion.", "web": "Shake yourself from the dust! Arise, sit up, Jerusalem! Release yourself from the bonds of your neck, captive daughter of Zion!", "bsb": "Shake off your dust! Rise up and sit on your throne, O Jerusalem. Remove the chains from your neck, O captive Daughter of Zion.", "asv": "Shake thyself from the dust; arise, sit on thy throne, O Jerusalem: loose thyself from the bonds of thy neck, O captive daughter of Zion.", "ylt": "Shake thyself from dust, arise, sit, O Jerusalem, Bands of thy neck have loosed themselves, O captive, daughter of Zion.", "dra": "Shake thyself from the dust, arise, sit up, O Jerusalem: loose the bonds from off thy neck, O captive daughter of Sion.", "bbe": "Make yourself clean from the dust; up! and take the seat of your power, O Jerusalem: the bands of your neck are loose, O prisoned daughter of Zion.", "geneva": "Shake thy selfe from the dust: arise, and sit downe, O Ierusalem: loose the bandes of thy necke, O thou captiue daughter, Zion.", "wycliffe": "Jerusalem, be thou schakun out of dust; rise thou, sitte thou; thou douyter of Sion, prisoner, vnbynde the boondis of thi necke.", "rotherham": "Shake thyself from the dust arise—sit down O Jerusalem,—Loose thyself from the bonds of thy neck, O captive! daughter of Zion!", "darby": "Shake thyself from the dust; arise, sit down, Jerusalem: loose thyself from the bands of thy neck, captive daughter of Zion.", "twenty": "", "jps": "Shake thyself from the dust; arise, and sit down, O Jerusalem; loose thyself from the bands of thy neck, O captive daughter of Zion.", "acv": "Shake thyself from the dust. Arise, sit up, O Jerusalem. Loose thyself from the bonds of thy neck, O captive daughter of Zion.", "anderson": "", "haweis": "", "noyes": "Shake thyself from the dust, Arise and sit erect, O Jerusalem! Loose thyself from the bands of thy neck, O captive daughter of Zion!", "webster": "Shake thyself from the dust; arise, [and] sit down, O Jerusalem: loose thyself from the bands of thy neck, O captive daughter of Zion.", "vulgate": "excutere de pulvere consurge sede Hierusalem solve vincula colli tui captiva filia Sion;", "brenton": "Shake off the dust and arise; sit down, Jerusalem: put off the band of thy neck, captive daughter of Sion."}}, {"v": 3, "ref": "52:3", "o": "כִּֽי כֹה֙ אָמַ֣ר יְהוָ֔ה חִנָּ֖ם נִמְכַּרְתֶּ֑ם וְ/לֹ֥א בְ/כֶ֖סֶף תִּגָּאֵֽלוּ", "en": {"kjv": "For thus saith the Lord, Ye have sold yourselves for nought; and ye shall be redeemed without money.", "web": "For thus says Yahweh, “You were sold for nothing; and you shall be redeemed without money.”", "bsb": "For this is what the LORD says: “You were sold for nothing, and without money you will be redeemed.”", "asv": "For thus saith Jehovah, Ye were sold for nought; and ye shall be redeemed without money.", "ylt": "For thus said Jehovah: `For nought ye have been sold, And not by money are ye redeemed.'", "dra": "For thus saith the Lord: You were sold gratis, and you shall be redeemed, without money.", "bbe": "For the Lord says, You were given for nothing, and you will be made free without price.", "geneva": "For thus sayeth the Lord, Yee were solde for naught: therefore shall ye be redeemed without money.", "wycliffe": "For the Lord seith these thingis, Ye ben seeld without cause, and ye schulen be ayenbouyt with out siluer.", "rotherham": "For, thus, saith Yahweh, For nought, ye sold yourselves,—And not with silver, shall ye be redeemed,", "darby": "For thus saith Jehovah: Ye have sold yourselves for nought, and ye shall be redeemed without money.", "twenty": "", "jps": "For thus saith HaShem: ye were sold for nought; and ye shall be redeemed without money.", "acv": "For thus says Jehovah: Ye were sold for nothing, and ye shall be redeemed without money.", "anderson": "", "haweis": "", "noyes": "For thus saith Jehovah: For naught were ye sold, And without money shall ye be ransomed.", "webster": "For thus saith the LORD, Ye have sold yourselves for naught; and ye shall be redeemed without money.", "vulgate": "quia haec dicit Dominus gratis venundati estis et sine argento redimemini;", "brenton": "For thus saith the Lord, Ye have been sold for nought; and ye shall not be ransomed with silver."}}, {"v": 4, "ref": "52:4", "o": "כִּ֣י כֹ֤ה אָמַר֙ אֲדֹנָ֣/י יְהוִ֔ה מִצְרַ֛יִם יָֽרַד עַמִּ֥/י בָ/רִֽאשֹׁנָ֖ה לָ/ג֣וּר שָׁ֑ם וְ/אַשּׁ֖וּר בְּ/אֶ֥פֶס עֲשָׁקֽ/וֹ", "en": {"kjv": "For thus saith the Lord God, My people went down aforetime into Egypt to sojourn there; and the Assyrian oppressed them without cause.", "web": "For thus says the Lord Yahweh, “My people went down at the first into Egypt to live there: and the Assyrian has oppressed them without cause.", "bsb": "For this is what the Lord GOD says: “At first My people went down to Egypt to live, then Assyria oppressed them without cause.", "asv": "For thus saith the Lord Jehovah, My people went down at the first into Egypt to sojourn there: and the Assyrian hath oppressed them without cause.", "ylt": "For thus said the Lord Jehovah: `To Egypt My people went down at first to sojourn there, And Asshur--for nought he hath oppressed it.", "dra": "For thus saith the Lord God: My people went down into Egypt at the beginning to sojourn there: and the Assyrian hath oppressed them without any cause at all.", "bbe": "For the Lord God says, My people went down at first into Egypt, to get a place for themselves there: and the Assyrian put a cruel yoke on them without cause.", "geneva": "For thus saith the Lord God, My people went downe afore time into Egypt to soiourne there, and Asshur oppressed them without cause.", "wycliffe": "For the Lord God seith these thingis, Mi puple in the bigynnyng yede doun in to Egipt, that it schulde be there `an erthe tiliere, and Assur falsli calengide it with out ony cause.", "rotherham": "For, thus, saith My Lord, Yahweh, To Egypt, went down my people at first to sojourn there,—But, Assyria, without cause, hath oppressed him.", "darby": "For thus saith the Lord Jehovah: My people went down at the first into Egypt to sojourn there, and Assyria oppressed them without cause;", "twenty": "", "jps": "For thus saith the L-rd GOD: My people went down aforetime into Egypt to sojourn there; and the Assyrian oppressed them without cause.", "acv": "For thus says the lord Jehovah, My people went down at the first into Egypt to sojourn there. And the Assyrian has oppressed them without cause.", "anderson": "", "haweis": "", "noyes": "For thus saith the Lord Jehovah: My people went down to Egypt formerly to sojourn there, And the Assyrian oppressed them without cause.", "webster": "For thus saith the Lord GOD, My people went down formerly into Egypt to sojourn there; and the Assyrian oppressed them without cause.", "vulgate": "quia haec dicit Dominus Deus in Aegyptum descendit populus meus in principio ut colonus esset ibi et Assur absque ulla causa calumniatus est eum;", "brenton": "Thus saith the Lord, My people went down before to Egypt to sojourn there; and were carried away forcibly to the Assyrians."}}, {"v": 5, "ref": "52:5", "o": "וְ/עַתָּ֤ה מי ל/י מַה לִּ/י פֹה֙ נְאֻם יְהוָ֔ה כִּֽי לֻקַּ֥ח עַמִּ֖/י חִנָּ֑ם משל/ו מֹשְׁלָ֤י/ו יְהֵילִ֨ילוּ֙ נְאֻם יְהוָ֔ה וְ/תָמִ֥יד כָּל הַ/יּ֖וֹם שְׁמִ֥/י מִנֹּאָֽץ", "en": {"kjv": "Now therefore, what have I here, saith the Lord, that my people is taken away for nought? they that rule over them make them to howl, saith the Lord; and my name continually every day is blasphemed.", "web": "“Now therefore, what do I do here,” says Yahweh, “seeing that my people are taken away for nothing? Those who rule over them mock,” says Yahweh, “and my name continually all the day is blasphemed.", "bsb": "And now what have I here? declares the LORD. For My people have been taken without cause; those who rule them taunt, declares the LORD, and My name is blasphemed continually all day long.", "asv": "Now therefore, what do I here, saith Jehovah, seeing that my people is taken away for nought? they that rule over them do howl, saith Jehovah, and my name continually all the day is blasphemed.", "ylt": "And now, what--to Me here, An affirmation of Jehovah, That taken is My people for nought? Its rulers cause howling, --an affirmation of Jehovah, And continually all the day My name is despised.", "dra": "And now what have I here, saith the Lord: for my people is taken away gratis. They that rule over them treat them unjustly, saith the Lord, and my name is continually blasphemed all the day long.", "bbe": "Now then, what have I here? says the Lord, for my people are taken away without cause; they are made waste and give cries of sorrow, says the Lord, and all the day the nations put shame on my name.", "geneva": "Nowe therefore what haue I here, saith the Lord, that my people is taken away for naught, and they that rule ouer them, make them to howle, saith the Lord? and my Name all the day continually is blasphemed?", "wycliffe": "And now what is to me here? seith the Lord; for my puple is takun awei with out cause; the lordis therof doen wickidli, seith the Lord, and my name is blasfemyd contynueli al dai.", "rotherham": "Now, therefore, what do I here? Demandeth Yahweh. That my people have been taken away for nought? They who rule them, do howl, Declareth Yahweh, And, continually—all the day, is my Name brought into contempt.", "darby": "and now, what have I here, saith Jehovah, that my people hath been taken away for nought? They that rule over them make them to howl, saith Jehovah; and continually all the day is my name scorned.", "twenty": "", "jps": "Now therefore, what do I here, saith HaShem, seeing that My people is taken away for nought? They that rule over them do howl, saith HaShem, and My name continually all the day is blasphemed.", "acv": "Now therefore, what do I do here, says Jehovah, seeing that my people are taken away for nothing? Those who rule over them howl, says Jehovah, and because of you my name is continually blasphemed among the Gentiles.", "anderson": "", "haweis": "", "noyes": "And now, what have I here to do, saith the Lord, When my people is taken away for naught, And their tyrants exult, saith Jehovah, And all the day long my name is blasphemed.", "webster": "Now therefore, what have I here, saith the LORD, that my people is taken away for naught? they that rule over them make them to howl, saith the LORD; and my name continually every day [is] blasphemed.", "vulgate": "et nunc quid mihi est hic dicit Dominus quoniam ablatus est populus meus gratis dominatores eius inique agunt dicit Dominus et iugiter tota die nomen meum blasphematur;", "brenton": "And now why are ye here? Thus saith the Lord, Because my people was taken for nothing, wonder ye and howl. Thus saith the Lord, On account of you my name is continually blasphemed among the Gentiles."}}, {"v": 6, "ref": "52:6", "o": "לָ/כֵ֛ן יֵדַ֥ע עַמִּ֖/י שְׁמִ֑/י לָ/כֵן֙ בַּ/יּ֣וֹם הַ/ה֔וּא כִּֽי אֲנִי ה֥וּא הַֽ/מְדַבֵּ֖ר הִנֵּֽ/נִי", "en": {"kjv": "Therefore my people shall know my name: therefore they shall know in that day that I am he that doth speak: behold, it is I.", "web": "Therefore my people shall know my name. Therefore they shall know in that day that I am he who speaks; behold, it is I.”", "bsb": "Therefore My people will know My name; therefore they will know on that day that I am He who speaks. Here I am!”", "asv": "Therefore my people shall know my name: therefore they shall know in that day that I am he that doth speak; behold, it is I.", "ylt": "Therefore doth My people know My name, Therefore, in that day, Surely I am He who is speaking, behold Me.'", "dra": "Therefore my people shall know my name in that day: for I myself that spoke, behold I am here.", "bbe": "For this cause I will make my name clear to my people; in that day they will be certain that it is my word which comes to them; see, here am I.", "geneva": "Therefore my people shall know my Name: therefore they shall know in that day, that I am he that doe speake: beholde, it is I.", "wycliffe": "For this thing my puple schal knowe my name in that day, for lo! Y my silf that spak, am present.", "rotherham": "Therefore, shall my people acknowledge my Name: Therefore, in that day, shall they acknowledge that, I, am the same, even I who am speaking,—Here, I am,", "darby": "Therefore my people shall know my name; therefore [they shall know] in that day that I [am] HE, that saith, Here am I.", "twenty": "", "jps": "Therefore My people shall know My name; therefore they shall know in that day that I, even He that spoke, behold, here I am.", "acv": "Therefore my people shall know my name. Therefore they shall know in that day that I am he who speaks, Behold, it is I.", "anderson": "", "haweis": "", "noyes": "Therefore shall my people know my name; Therefore in that day shall they know That I am he that said, Behold, here am I!", "webster": "Therefore my people shall know my name: therefore [they shall know] in that day that I [am] he that doth speak: behold, [it is] I.", "vulgate": "propter hoc sciet populus meus nomen meum in die illa quia ego ipse qui loquebar ecce adsum;", "brenton": "Therefore shall my people know my name in that day, for I am he that speaks: I am present,"}}, {"v": 7, "ref": "52:7", "o": "מַה נָּאו֨וּ עַל הֶ/הָרִ֜ים רַגְלֵ֣י מְבַשֵּׂ֗ר מַשְׁמִ֧יעַ שָׁל֛וֹם מְבַשֵּׂ֥ר ט֖וֹב מַשְׁמִ֣יעַ יְשׁוּעָ֑ה אֹמֵ֥ר לְ/צִיּ֖וֹן מָלַ֥ךְ אֱלֹהָֽיִ/ךְ", "en": {"kjv": "How beautiful upon the mountains are the feet of him that bringeth good tidings, that publisheth peace; that bringeth good tidings of good, that publisheth salvation; that saith unto Zion, Thy God reigneth!", "web": "How beautiful on the mountains are the feet of him who brings good news, who publishes peace, who brings good news of good, who publishes salvation, who says to Zion, “Your God reigns!”", "bsb": "How beautiful on the mountains are the feet of those who bring good news, who proclaim peace, who bring good tidings, who proclaim salvation, who say to Zion, “Your God reigns!”", "asv": "How beautiful upon the mountains are the feet of him that bringeth good tidings, that publisheth peace, that bringeth good tidings of good, that publisheth salvation, that saith unto Zion, Thy God reigneth!", "ylt": "How comely on the mountains, Have been the feet of one proclaiming tidings, Sounding peace, proclaiming good tidings, Sounding salvation, Saying to Zion, `Reigned hath thy God.'", "dra": "How beautiful upon the mountains are the feet of him that bringeth good tidings, and that preacheth peace: of him that sheweth forth good, that preacheth salvation, that saith to Sion: Thy God shall reign!", "bbe": "How beautiful on the mountains are the feet of him who comes with good news, who gives word of peace, saying that salvation is near; who says to Zion, Your God is ruling!", "geneva": "How beautifull vpon the mountaines are the feete of him, that declareth and publisheth peace? that declareth good tidings, and publisheth saluation, saying vnto Zion, Thy God reigneth?", "wycliffe": "Ful faire ben the feet of hym that tellith, and prechith pees on hillis, of hym that tellith good, of hym that prechith helthe, and seith, Sion, thi God schal regne.", "rotherham": "How beautiful, upon the mountains are the feet—Of him That bringeth good tidings, That publisheth peace, That bringeth good tidings of blessing, That publisheth salvation,—That saith unto Zion, Thy God, hath become king.", "darby": "How beautiful upon the mountains are the feet of him that announceth glad tidings, that publisheth peace; that announceth glad tidings of good, that publisheth salvation, that saith unto Zion, ThyGod reigneth!", "twenty": "", "jps": "How beautiful upon the mountains are the feet of the messenger of good tidings, that announceth peace, the harbinger of good tidings, that announceth salvation; that saith unto Zion: 'Thy G-d reigneth!'", "acv": "How beautiful upon the mountains are the feet of him who brings good news, who publishes peace, who brings good news of good, who publishes salvation, who says to Zion, Thy God reigns!", "anderson": "", "haweis": "", "noyes": "How beautiful upon the mountains are the feet of him that bringeth good tidings, of him that proclaimeth peace! That bringeth good tidings, that proclaimeth salvation! That saith to Zion, \"Thy God is king!\"", "webster": "How beautiful upon the mountains are the feet of him that bringeth good tidings, that publisheth peace; that bringeth good tidings of good, that publisheth salvation; that saith to Zion, Thy God reigneth!", "vulgate": "quam pulchri super montes pedes adnuntiantis et praedicantis pacem adnuntiantis bonum praedicantis salutem dicentis Sion regnavit Deus tuus;", "brenton": "as a season of beauty upon the mountains, as the feet of one preaching glad tidings of peace, as one preaching good news: for I will publish thy salvation, saying, O Sion, thy God shall reign."}}, {"v": 8, "ref": "52:8", "o": "ק֥וֹל צֹפַ֛יִ/ךְ נָ֥שְׂאוּ ק֖וֹל יַחְדָּ֣ו יְרַנֵּ֑נוּ כִּ֣י עַ֤יִן בְּ/עַ֨יִן֙ יִרְא֔וּ בְּ/שׁ֥וּב יְהוָ֖ה צִיּֽוֹן", "en": {"kjv": "Thy watchmen shall lift up the voice; with the voice together shall they sing: for they shall see eye to eye, when the Lord shall bring again Zion.", "web": "The voice of your watchmen! they lift up the voice, together do they sing; for they shall see eye to eye, when Yahweh returns to Zion.", "bsb": "Listen! Your watchmen lift up their voices, together they shout for joy. For every eye will see when the LORD returns to Zion.", "asv": "The voice of thy watchmen! they lift up the voice, together do they sing; for they shall see eye to eye, when Jehovah returneth to Zion.", "ylt": "The voice of thy watchmen! They have lifted up the voice, together they cry aloud, Because eye to eye they see, in Jehovah's turning back to Zion.", "dra": "The voice of thy watchmen: they have lifted up their voice, they shall praise together: for they shall see eye to eye when the Lord shall convert Sion.", "bbe": "The voice of your watchmen! their voices are loud in song together; for they will see him, eye to eye, when the Lord comes back to Zion.", "geneva": "The voyce of thy watchmen shalbe heard: they shall lift vp their voyce, and shoute together: for they shall see eye to eye, when the Lord shall bring againe Zion.", "wycliffe": "The vois of thi biholderis; thei reisiden the vois, thei schulen herie togidere; for thei schulen se with iye to iye, whanne the Lord hath conuertid Sion.", "rotherham": "The voice of thy watchmen! They have uplifted a voice Together, do they renew the shout of triumph,—For eye to eye, shall they see, When Yahweh returneth to Zion.", "darby": "— The voice of thy watchmen, they lift up the voice, they sing aloud together; for they shall see eye to eye, when Jehovah shall bring again Zion.", "twenty": "", "jps": "Hark, thy watchmen! they lift up the voice, together do they sing; for they shall see, eye to eye, HaShem returning to Zion.", "acv": "The voice of thy watchmen! They lift up the voice; they sing together. For they shall see eye to eye, when Jehovah returns to Zion.", "anderson": "", "haweis": "", "noyes": "Hark! the voice of thy watchmen! They lift up the voice together; yea, they shout! For eye to eye shall they behold, When Jehovah returneth to Zion.", "webster": "Thy watchmen shall lift up the voice; with the voice together shall they sing: for they shall see eye to eye, when the LORD shall bring again Zion.", "vulgate": "vox speculatorum tuorum levaverunt vocem simul laudabunt quia oculum ad oculum videbunt cum converterit Dominus Sion;", "brenton": "For the voice of them that guard thee is exalted, and with the voice together they shall rejoice: for eyes shall look to eyes, when the Lord shall have mercy upon Sion."}}, {"v": 9, "ref": "52:9", "o": "פִּצְח֤וּ רַנְּנוּ֙ יַחְדָּ֔ו חָרְב֖וֹת יְרוּשָׁלִָ֑ם כִּֽי נִחַ֤ם יְהוָה֙ עַמּ֔/וֹ גָּאַ֖ל יְרוּשָׁלִָֽם", "en": {"kjv": "Break forth into joy, sing together, ye waste places of Jerusalem: for the Lord hath comforted his people, he hath redeemed Jerusalem.", "web": "Break out into joy, sing together, you waste places of Jerusalem; for Yahweh has comforted his people, he has redeemed Jerusalem.", "bsb": "Break forth in joy, sing together, O ruins of Jerusalem, for the LORD has comforted His people; He has redeemed Jerusalem.", "asv": "Break forth into joy, sing together, ye waste places of Jerusalem; for Jehovah hath comforted his people, he hath redeemed Jerusalem.", "ylt": "Break forth, sing together, O wastes of Jerusalem, For Jehovah hath comforted His people, He hath redeemed Jerusalem.", "dra": "Rejoice, and give praise together, O ye deserts of Jerusalem: for the Lord hath comforted his people: he hath redeemed Jerusalem.", "bbe": "Give sounds of joy, make melody together, waste places of Jerusalem: for the Lord has given comfort to his people, he has taken up the cause of Jerusalem.", "geneva": "O ye desolate places of Ierusalem, bee glad and reioyce together: for the Lord hath comforted his people: he hath redeemed Ierusalem.", "wycliffe": "The forsakun thingis of Jerusalem, make ye ioie, and herie ye togidere; for the Lord hath coumfortid his puple, he hath ayenbouyt Jerusalem.", "rotherham": "Break forth, shout in triumph together, ye waste places of Jerusalem,—For Yahweh Hath comforted his people, Hath redeemed Jerusalem:", "darby": "Break forth, sing aloud together, waste places of Jerusalem; for Jehovah comforteth his people, he hath redeemed Jerusalem.", "twenty": "", "jps": "Break forth into joy, sing together, ye waste places of Jerusalem; for HaShem hath comforted His people, He hath redeemed Jerusalem.", "acv": "Break forth into joy, sing together, ye waste places of Jerusalem, for Jehovah has comforted his people. He has redeemed Jerusalem.", "anderson": "", "haweis": "", "noyes": "Break forth into joy; shout together, ye ruins of Jerusalem! For Jehovah hath pity on his people; he redeemeth Jerusalem.", "webster": "Break forth into joy, sing together, ye waste places of Jerusalem: for the LORD hath comforted his people, he hath redeemed Jerusalem.", "vulgate": "gaudete et laudate simul deserta Hierusalem quia consolatus est Dominus populum suum redemit Hierusalem;", "brenton": "Let the waste places of Jerusalem break forth in joy together, because the Lord has had mercy upon her, and has delivered Jerusalem."}}, {"v": 10, "ref": "52:10", "o": "חָשַׂ֤ף יְהוָה֙ אֶת זְר֣וֹעַ קָדְשׁ֔/וֹ לְ/עֵינֵ֖י כָּל הַ/גּוֹיִ֑ם וְ/רָאוּ֙ כָּל אַפְסֵי אָ֔רֶץ אֵ֖ת יְשׁוּעַ֥ת אֱלֹהֵֽי/נוּ", "en": {"kjv": "The Lord hath made bare his holy arm in the eyes of all the nations; and all the ends of the earth shall see the salvation of our God.", "web": "Yahweh has made bare his holy arm in the eyes of all the nations; and all the ends of the earth have seen the salvation of our God.", "bsb": "The LORD has bared His holy arm in the sight of all the nations; all the ends of the earth will see the salvation of our God.", "asv": "Jehovah hath made bare his holy arm in the eyes of all the nations; and all the ends of the earth have seen the salvation of our God.", "ylt": "Jehovah hath made bare His holy arm Before the eyes of all the nations, And seen have all the ends of the earth, The salvation of our God.", "dra": "The Lord hath prepared his holy arm in the sight of all the Gentiles: and all the ends of the earth shall see the salvation of our God.", "bbe": "The Lord has let his holy arm be seen by the eyes of all nations; and all the ends of the earth will see the salvation of our God.", "geneva": "The Lord hath made bare his holy arme in the sight of all the Gentiles, and all the endes of the earth shall see the saluation of our God.", "wycliffe": "The Lord hath maad redi his hooli arm in the iyen of alle folkis, and alle the endis of the erthe schulen se the helthe of oure God.", "rotherham": "Yahweh hath bared his holy arm, in the eyes of all the nations, So shall all the ends of the earth see the salvation of our God.", "darby": "Jehovah hath made bare his holy arm in the sight of all the nations; and all the ends of the earth shall see the salvation of ourGod.", "twenty": "", "jps": "HaShem hath made bare His holy arm in the eyes of all the nations; and all the ends of the earth shall see the salvation of our G-d.", "acv": "Jehovah has made bare his holy arm in the eyes of all the nations, and all the ends of the earth have seen the salvation of our God.", "anderson": "", "haweis": "", "noyes": "Jehovah maketh bare his holy arm In the sight of all the nations; All the ends of the earth Behold the salvation from our God.", "webster": "The LORD hath made bare his holy arm in the eyes of all the nations: and all the ends of the earth shall see the salvation of our God.", "vulgate": "paravit Dominus brachium sanctum suum in oculis omnium gentium et videbunt omnes fines terrae salutare Dei nostri;", "brenton": "And the Lord shall reveal his holy arm in the sight of all the nations; and all the ends of the earth shall see the salvation that comes from our God."}}, {"v": 11, "ref": "52:11", "o": "ס֤וּרוּ ס֨וּרוּ֙ צְא֣וּ מִ/שָּׁ֔ם טָמֵ֖א אַל תִּגָּ֑עוּ צְא֣וּ מִ/תּוֹכָ֔/הּ הִבָּ֕רוּ נֹשְׂאֵ֖י כְּלֵ֥י יְהוָֽה", "en": {"kjv": "Depart ye, depart ye, go ye out from thence, touch no unclean thing; go ye out of the midst of her; be ye clean, that bear the vessels of the Lord.", "web": "Depart, depart, go out from there, touch no unclean thing! Go out of the midst of her! Cleanse yourselves, you who bear the vessels of Yahweh.", "bsb": "Depart, depart, go out from there! Touch no unclean thing; come out from it, purify yourselves, you who carry the vessels of the LORD.", "asv": "Depart ye, depart ye, go ye out from thence, touch no unclean thing; go ye out of the midst of her; cleanse yourselves, ye that bear the vessels of Jehovah.", "ylt": "Turn aside, turn aside, go out thence, The unclean touch not, go out from her midst, Be ye pure, who are bearing the weapons of Jehovah.", "dra": "Depart, depart, go ye out from thence, touch no unclean thing: go out of the midst of her, be ye clean, you that carry the vessels of the Lord.", "bbe": "Away! away! go out from there, touching no unclean thing; go out from among her; be clean, you who take up the vessels of the Lord.", "geneva": "Depart, depart ye: goe out from thence and touche no vncleane thing: goe out of the middes of her: be ye cleane, that beare the vessels of the Lord.", "wycliffe": "Go ye awei, go ye awei, go ye out fro thennus; nyle ye touche defoulid thing, go ye out fro the myddis therof; be ye clensid, that beren the vessels of the Lord.", "rotherham": "Away! away! come, forth from thence!—Nought unclean, may ye touch,—Come forth out of her midst, Purify yourselves, ye who are to carry the vessels of Yahweh;", "darby": "— Depart, depart, go out from thence, touch not what is unclean; go out of the midst of her, be ye clean, that bear the vessels of Jehovah.", "twenty": "", "jps": "Depart ye, depart ye, go ye out from thence, touch no unclean thing; go ye out of the midst of her; be ye clean, ye that bear the vessels of HaShem.", "acv": "Depart ye, depart ye, go ye out from there. Touch no unclean thing. Go ye out of the midst of her. Cleanse yourselves, ye who bear the vessels of Jehovah.", "anderson": "", "haweis": "", "noyes": "Depart, depart ye; go ye out from thence; Touch no unclean thing! Go ye out from the midst of her; Be ye clean, ye that bear the vessels of Jehovah!", "webster": "Depart ye, depart ye, go ye out from thence, touch no unclean [thing]; go ye out of the midst of her; be ye clean, that bear the vessels of the LORD.", "vulgate": "recedite recedite exite inde pollutum nolite tangere exite de medio eius mundamini qui fertis vasa Domini;", "brenton": "Depart ye, depart, go out from thence, and touch not the unclean thing; go ye out from the midst of her; separate yourselves, ye that bear the vessels of the Lord."}}, {"v": 12, "ref": "52:12", "o": "כִּ֣י לֹ֤א בְ/חִפָּזוֹן֙ תֵּצֵ֔אוּ וּ/בִ/מְנוּסָ֖ה לֹ֣א תֵלֵכ֑וּ/ן כִּֽי הֹלֵ֤ךְ לִ/פְנֵי/כֶם֙ יְהוָ֔ה וּ/מְאַסִּפְ/כֶ֖ם אֱלֹהֵ֥י יִשְׂרָאֵֽל", "en": {"kjv": "For ye shall not go out with haste, nor go by flight: for the Lord will go before you; and the God of Israel will be your rereward.", "web": "For you shall not go out in haste, neither shall you go by flight: for Yahweh will go before you; and the God of Israel will be your rear guard.", "bsb": "For you will not leave in a hurry nor flee in haste, for the LORD goes before you, and the God of Israel is your rear guard.", "asv": "For ye shall not go out in haste, neither shall ye go by flight: for Jehovah will go before you; and the God of Israel will be your rearward.", "ylt": "For not in haste do ye go out, Yea, with flight ye go not on, For going before you is Jehovah, And gathering you is the God of Israel!", "dra": "For you shall not go out in a tumult, neither shall you make haste by flight: for the Lord will go before you, and the God of Israel will gather you together.", "bbe": "For you will not go out suddenly, and you will not go in flight: for the Lord will go before you, and the God of Israel will come after you to keep you.", "geneva": "For ye shall not goe out with haste, nor depart by fleeing away: but the Lord will goe before you, and the God of Israel will gather you together.", "wycliffe": "For ye schulen not go out in noyse, nether ye schulen haaste in fleynge awei; for whi the Lord schal go bifore you, and the God of Israel schal gadere you togidere.", "rotherham": "For, not in haste, shall ye come forth, Nor, by flight, shall ye journey,—For, your van-guard, is Yahweh, And, your rear-guard, the God of Israel.", "darby": "For ye shall not go out with haste, nor go by flight; for Jehovah will go before you, and theGod of Israel will be your rear-guard.", "twenty": "", "jps": "For ye shall not go out in haste, neither shall ye go by flight; for HaShem will go before you, and the G-d of Israel will be your rearward.", "acv": "For ye shall not go out in haste, nor shall ye go by flight. For Jehovah will go before you, and the God of Israel will be your rearward.", "anderson": "", "haweis": "", "noyes": "For not in haste shall ye go forth, Nor in flight shall ye pass along; For Jehovah shall march in your front, And the God of Israel bring up your rear.", "webster": "For ye shall not go out with haste, nor go by flight: for the LORD will go before you; and the God of Israel [will be] your rear-ward.", "vulgate": "quoniam non in tumultu exibitis nec in fuga properabitis praecedet enim vos Dominus et congregabit vos Deus Israhel;", "brenton": "For ye shall not go forth with tumult, neither go by flight: for the Lord shall go first in advance of you; and the God of Israel shall be he that brings up your rear."}}, {"v": 13, "ref": "52:13", "o": "הִנֵּ֥ה יַשְׂכִּ֖יל עַבְדִּ֑/י יָר֧וּם וְ/נִשָּׂ֛א וְ/גָבַ֖הּ מְאֹֽד", "en": {"kjv": "Behold, my servant shall deal prudently, he shall be exalted and extolled, and be very high.", "web": "Behold, my servant shall deal wisely, he shall be exalted and lifted up, and shall be very high.", "bsb": "Behold, My Servant will prosper; He will be raised and lifted up and highly exalted.", "asv": "Behold, my servant shall deal wisely, he shall be exalted and lifted up, and shall be very high.", "ylt": "Lo, My servant doth act wisely, He is high, and hath been lifted up, And hath been very high.", "dra": "Behold my servant shall understand, he shall be exalted, and extolled, and shall be exceeding high.", "bbe": "See, my servant will do well in his undertakings, he will be honoured, and lifted up, and be very high.", "geneva": "Beholde, my seruant shall prosper: he shall be exalted and extolled, and be very hie.", "wycliffe": "Lo! my seruaunt schal vndirstonde, and he schal be enhaunsid, and he schal be reisid, and he schal be ful hiy.", "rotherham": "Lo! my Servant, prospereth,—He riseth, and is lifted up, and becometh very high:", "darby": "Behold, my servant shall deal prudently; he shall be exalted and be lifted up, and be very high.", "twenty": "", "jps": "Behold, My servant shall prosper, he shall be exalted and lifted up, and shall be very high.", "acv": "Behold, my servant shall deal wisely. He shall be exalted and lifted up, and shall be very high.", "anderson": "", "haweis": "", "noyes": "Behold, my servant shall prosper; He shall be lifted up, and set on high, and greatly exalted.", "webster": "Behold, my servant shall deal prudently, he shall be exalted and extolled, and be very high.", "vulgate": "ecce intelleget servus meus exaltabitur et elevabitur et sublimis erit valde;", "brenton": "Behold, my servant shall understand, and be exalted, and glorified exceedingly."}}, {"v": 14, "ref": "52:14", "o": "כַּ/אֲשֶׁ֨ר שָׁמְמ֤וּ עָלֶ֨י/ךָ֙ רַבִּ֔ים כֵּן מִשְׁחַ֥ת מֵ/אִ֖ישׁ מַרְאֵ֑/הוּ וְ/תֹאֲר֖/וֹ מִ/בְּנֵ֥י אָדָֽם", "en": {"kjv": "As many were astonied at thee; his visage was so marred more than any man, and his form more than the sons of men:", "web": "Like as many were astonished at you (his appearance was marred more than any man, and his form more than the sons of men),", "bsb": "Just as many were appalled at Him— His appearance was disfigured beyond that of any man, and His form was marred beyond human likeness—", "asv": "Like as many were astonished at thee (his visage was so marred more than any man, and his form more than the sons of men),", "ylt": "As astonished at thee have been many, (So marred by man his appearance, And his form by sons of men.)", "dra": "As many have been astonished at thee, so shall his visage be inglorious among men, and his form among the sons of men.", "bbe": "As peoples were surprised at him, And his face was not beautiful, so as to be desired: his face was so changed by disease as to be unlike that of a man, and his form was no longer that of the sons of men.", "geneva": "As many were astonied at thee (his visage was so deformed of men, and his forme of the sonnes of men) so shall hee sprinkle many nations: the Kings shall shut their mouthes at him: for that which had not bene tolde them, shall they see, and that which they had not heard, shall they vnderstande.", "wycliffe": "As many men wondriden on hym, so his biholdyng schal be with out glorie among men, and the fourme of hym among the sones of men.", "rotherham": "The more that Many, were amazed at thee, So marred, beyond any man’s, was his appearance,—And his form, beyond the sons of men,", "darby": "As many were astonished at thee — his visage was so marred more than any man, and his form more than the children of men", "twenty": "", "jps": "According as many were appalled at thee--so marred was his visage unlike that of a man, and his form unlike that of the sons of men--", "acv": "Just as many were astonished at thee (his visage was so marred, more than any man, and his form more than the sons of men),", "anderson": "", "haweis": "", "noyes": "As many were amazed at the sight of him,—So disfigured and scarcely human was his visage, And so unlike that of a man was his form,—", "webster": "As many were astonished at thee; his visage was so marred more than any man, and his form more than the sons of men:", "vulgate": "sicut obstipuerunt super te multi sic inglorius erit inter viros aspectus eius et forma eius inter filios hominum;", "brenton": "As many shall be amazed at thee, so shall thy face be without glory from men, and thy glory shall not be honoured by the sons of men."}}, {"v": 15, "ref": "52:15", "o": "כֵּ֤ן יַזֶּה֙ גּוֹיִ֣ם רַבִּ֔ים עָלָ֛י/ו יִקְפְּצ֥וּ מְלָכִ֖ים פִּי/הֶ֑ם כִּ֠י אֲשֶׁ֨ר לֹֽא סֻפַּ֤ר לָ/הֶם֙ רָא֔וּ וַ/אֲשֶׁ֥ר לֹֽא שָׁמְע֖וּ הִתְבּוֹנָֽנוּ", "en": {"kjv": "So shall he sprinkle many nations; the kings shall shut their mouths at him: for that which had not been told them shall they see; and that which they had not heard shall they consider.", "web": "so shall he sprinkle many nations; kings shall shut their mouths at him: for that which had not been told them shall they see; and that which they had not heard shall they understand.", "bsb": "so He will sprinkle many nations. Kings will shut their mouths because of Him. For they will see what they have not been told, and they will understand what they have not heard.", "asv": "so shall he sprinkle many nations; kings shall shut their mouths at him: for that which had not been told them shall they see; and that which they had not heard shall they understand.", "ylt": "So doth he sprinkle many nations. Concerning him kings shut their mouth, For that which was not recounted to them they have seen, And that which they had not heard they have understood!", "dra": "He shall sprinkle many nations, kings shall shut their mouth at him: for they to whom it was not told of him, have seen: and they that heard not, have beheld.", "bbe": "So will nations give him honour; kings will keep quiet because of him: for what had not been made clear to them they will see; and they will give their minds to what had not come to their ears.", "geneva": "", "wycliffe": "He schal bisprenge many folkis; kyngis schulen holde togidere her mouth on him; for thei schulen se, to whiche it was not teld of hym, and thei that herden not, bihelden.", "rotherham": "The more doth he startle Many nations, Before him, have kings closed their mouth,—For, that which had not been related to them, have they seen, And that which they had not heard, haw they diligently considered.", "darby": "— so shall he astonish many nations; kings shall shut their mouths at him: for what had not been told them shall they see, and what they had not heard shall they consider.", "twenty": "", "jps": "So shall he startle many nations, kings shall shut their mouths because of him; for that which had not been told them shall they see, and that which they had not heard shall they perceive.", "acv": "so shall he sprinkle many nations. Kings shall shut their mouths at him. For that which had not been told them they shall see, and that which they had not heard they shall understand.", "anderson": "", "haweis": "", "noyes": "So shall he cause many nations to exult on account of him; Kings shall shut their mouths before him. For what had never been told them shall they see, And what they never heard shall they perceive.", "webster": "So shall he sprinkle many nations; the kings shall shut their mouths at him: for [that] which had not been told them shall they see; and [that] which they had not heard shall they consider.", "vulgate": "iste asperget gentes multas super ipsum continebunt reges os suum quia quibus non est narratum de eo viderunt et qui non audierunt contemplati sunt;", "brenton": "Thus shall many nations wonder at him; and kings shall keep their mouths shut: for they to whom no report was brought concerning him, shall see; and they who have not heard, shall consider."}}]}, {"c": 53, "verses": [{"v": 1, "ref": "53:1", "o": "מִ֥י הֶאֱמִ֖ין לִ/שְׁמֻעָתֵ֑/נוּ וּ/זְר֥וֹעַ יְהוָ֖ה עַל מִ֥י נִגְלָֽתָה", "en": {"kjv": "Who hath believed our report? and to whom is the arm of the Lord revealed?", "web": "Who has believed our message? To whom has the arm of Yahweh been revealed?", "bsb": "Who has believed our message? And to whom has the arm of the LORD been revealed?", "asv": "Who hath believed our message? and to whom hath the arm of Jehovah been revealed?", "ylt": "Who hath given credence to that which we heard? And the arm of Jehovah, On whom hath it been revealed?", "dra": "Who a hath believed our report? and to whom is the arm of the Lord revealed?", "bbe": "Who would have had faith in the word which has come to our ears, and to whom had the arm of the Lord been unveiled?", "geneva": "Who will beleeue our report? and to whom is the arme of the Lord reueiled?", "wycliffe": "Who bileuyde to oure heryng? and to whom is the arm of the Lord schewide?", "rotherham": "Who believed what we have heard? And, the arm of Yahweh, to whom was it revealed?", "darby": "Who hath believed our report? and to whom hath the arm of Jehovah been revealed?", "twenty": "", "jps": "'Who would have believed our report? And to whom hath the arm of HaShem been revealed?", "acv": "Who has believed our report? And to whom has the arm of Jehovah been revealed?", "anderson": "", "haweis": "", "noyes": "Who hath believed our report, And to whom hath the arm of Jehovah been revealed?", "webster": "Who hath believed our report? and to whom is the arm of the LORD revealed?", "vulgate": "quis credidit auditui nostro et brachium Domini cui revelatum est;", "brenton": "O Lord, who has believed our report? and to whom has the arm of the Lord been revealed?"}}, {"v": 2, "ref": "53:2", "o": "וַ/יַּ֨עַל כַּ/יּוֹנֵ֜ק לְ/פָנָ֗י/ו וְ/כַ/שֹּׁ֨רֶשׁ֙ מֵ/אֶ֣רֶץ צִיָּ֔ה לֹא תֹ֥אַר ל֖/וֹ וְ/לֹ֣א הָדָ֑ר וְ/נִרְאֵ֥/הוּ וְ/לֹֽא מַרְאֶ֖ה וְ/נֶחְמְדֵֽ/הוּ", "en": {"kjv": "For he shall grow up before him as a tender plant, and as a root out of a dry ground: he hath no form nor comeliness; and when we shall see him, there is no beauty that we should desire him.", "web": "For he grew up before him as a tender plant, and as a root out of dry ground. He has no good looks or majesty. When we see him, there is no beauty that we should desire him.", "bsb": "He grew up before Him like a tender shoot, and like a root out of dry ground. He had no stately form or majesty to attract us, no beauty that we should desire Him.", "asv": "For he grew up before him as a tender plant, and as a root out of a dry ground: he hath no form nor comeliness; and when we see him, there is no beauty that we should desire him.", "ylt": "Yea, he cometh up as a tender plant before Him, And as a root out of a dry land, He hath no form, nor honour, when we observe him, Nor appearance, when we desire him.", "dra": "And he shall grow up as a tender plant before him, and as a root out of a thirsty ground: there is no beauty in him, nor comeliness: and we have seen him, and there was no sightliness, that we should be desirous of him:", "bbe": "For his growth was like that of a delicate plant before him, and like a root out of a dry place: he had no grace of form, to give us pleasure;", "geneva": "But hee shall growe vp before him as a branche, and as a roote out of a dry grounde: he hath neither forme nor beautie: when we shall see him, there shall be no forme that wee should desire him.", "wycliffe": "And he schal stie as a yerde bifore hym, and as a roote fro thirsti lond. And nether schap nether fairnesse was to hym; and we sien hym, and no biholdyng was;", "rotherham": "When he came up as a sapling before him. And as a root-sprout out of dry ground, He had neither beauty nor majesty,—When we beheld him, there was nothing to behold, that we should desire him;", "darby": "For he shall grow up before him as a tender sapling, and as a root out of dry ground: he hath no form nor lordliness, and when we see him, there is no beauty that we should desire him.", "twenty": "", "jps": "For he shot up right forth as a sapling, and as a root out of a dry ground; he had no form nor comeliness, that we should look upon him, nor beauty that we should delight in him.", "acv": "For he grew up before him as a tender plant, and as a root out of a dry ground. He has no form nor comeliness. And when we see him, there is no beauty that we should desire him.", "anderson": "", "haweis": "", "noyes": "For He grew up before him like a tender plant, Like a sucker from a dry soil; He had no form, nor comeliness, that we should look upon him, Nor beauty, that we should take pleasure in him.", "webster": "For he shall grow up before him as a tender plant, and as a root out of a dry ground: he hath no form nor comeliness; and when we shall see him, [there is] no beauty that we should desire him.", "vulgate": "et ascendet sicut virgultum coram eo et sicut radix de terra sitienti non est species ei neque decor et vidimus eum et non erat aspectus et desideravimus eum;", "brenton": "We brought a report as of a child before him; he is as a root in a thirsty land: he has no form nor comeliness; and we saw him, but he had no form nor beauty."}}, {"v": 3, "ref": "53:3", "o": "נִבְזֶה֙ וַ/חֲדַ֣ל אִישִׁ֔ים אִ֥ישׁ מַכְאֹב֖וֹת וִ/יד֣וּעַ חֹ֑לִי וּ/כְ/מַסְתֵּ֤ר פָּנִים֙ מִמֶּ֔/נּוּ נִבְזֶ֖ה וְ/לֹ֥א חֲשַׁבְנֻֽ/הוּ", "en": {"kjv": "He is despised and rejected of men; a man of sorrows, and acquainted with grief: and we hid as it were our faces from him; he was despised, and we esteemed him not.", "web": "He was despised, and rejected by men; a man of suffering, and acquainted with disease. He was despised as one from whom men hide their face; and we didn’t respect him.", "bsb": "He was despised and rejected by men, a man of sorrows, acquainted with grief. Like one from whom men hide their faces, He was despised, and we esteemed Him not.", "asv": "He was despised, and rejected of men; a man of sorrows, and acquainted with grief: and as one from whom men hide their face he was despised; and we esteemed him not.", "ylt": "He is despised, and left of men, A man of pains, and acquainted with sickness, And as one hiding the face from us, He is despised, and we esteemed him not.", "dra": "Despised, and the most abject of men, a man of sorrows, and acquainted with infirmity: and his look was as it were hidden and despised, whereupon we esteemed him not.", "bbe": "Men made sport of him, turning away from him; he was a man of sorrows, marked by disease; and like one from whom men's faces are turned away, he was looked down on, and we put no value on him.", "geneva": "He is despised and reiected of men: he is a man full of sorowes and hath experience of infirmities: we hidde as it were our faces from him: he was despised and we esteemed him not.", "wycliffe": "and we desiriden hym, dispisid, and the laste of men, a man of sorewis, and knowynge sikenesse. And his cheer was as hid and dispisid; wherfor and we arettiden not hym.", "rotherham": "Despised was he, and forsaken of men, Man of pains and familiar with sickness,—Yea, like one from whom the face is hidden, Despised, and we esteemed him not.", "darby": "He is despised and left alone of men; a man of sorrows, and acquainted with grief, and like one from whom [men] hide their faces; — despised, and we esteemed him not.", "twenty": "", "jps": "He was despised, and forsaken of men, a man of pains, and acquainted with disease, and as one from whom men hide their face: he was despised, and we esteemed him not.", "acv": "He was despised, and rejected by men, a man of sorrows, and acquainted with grief. And as him from whom men hide their face he was despised, and we esteemed him not.", "anderson": "", "haweis": "", "noyes": "He was despised, and forsaken of men, A man of sorrows, and acquainted with disease; As one from whom men hide their faces, He was despised, and we esteemed him not.", "webster": "He is despised and rejected by men; a man of sorrows, and acquainted with grief: and we hid as it were [our] faces from him; he was despised, and we esteemed him not.", "vulgate": "despectum et novissimum virorum virum dolorum et scientem infirmitatem et quasi absconditus vultus eius et despectus unde nec reputavimus eum;", "brenton": "But his form was ignoble, and inferior to that of the children of men; he was a man in suffering, and acquainted with the bearing of sickness, for his face is turned from us: he was dishonoured, and not esteemed."}}, {"v": 4, "ref": "53:4", "o": "אָכֵ֤ן חֳלָיֵ֨/נוּ֙ ה֣וּא נָשָׂ֔א וּ/מַכְאֹבֵ֖י/נוּ סְבָלָ֑/ם וַ/אֲנַ֣חְנוּ חֲשַׁבְנֻ֔/הוּ נָג֛וּעַ מֻכֵּ֥ה אֱלֹהִ֖ים וּ/מְעֻנֶּֽה", "en": {"kjv": "Surely he hath borne our griefs, and carried our sorrows: yet we did esteem him stricken, smitten of God, and afflicted.", "web": "Surely he has borne our sickness, and carried our suffering; yet we considered him plagued, struck by God, and afflicted.", "bsb": "Surely He took on our infirmities and carried our sorrows; yet we considered Him stricken by God, struck down and afflicted.", "asv": "Surely he hath borne our griefs, and carried our sorrows; yet we did esteem him stricken, smitten of God, and afflicted.", "ylt": "Surely our sicknesses he hath borne, And our pains--he hath carried them, And we--we have esteemed him plagued, Smitten of God, and afflicted.", "dra": "Surely he hath borne our infirmities and carried our sorrows: and we have thought him as it were a leper, and as one struck by God and afflicted.", "bbe": "But it was our pain he took, and our diseases were put on him: while to us he seemed as one diseased, on whom God's punishment had come.", "geneva": "Surely hee hath borne our infirmities, and caried our sorowes: yet wee did iudge him, as plagued, and smitten of God, and humbled.", "wycliffe": "Verili he suffride oure sikenessis, and he bar oure sorewis; and we arettiden hym as a mesel, and smytun of God, and maad low.", "rotherham": "Yet surely, our sicknesses, he, carried, And, as for our pains, he bare the burden of them,—But, we, accounted him stricken. Smitten of God and humbled,", "darby": "Surely he hath borne our griefs and carried our sorrows; and we, we did regard him stricken, smitten ofGod, and afflicted.", "twenty": "", "jps": "Surely our diseases he did bear, and our pains he carried; whereas we did esteem him stricken, smitten of G-d, and afflicted.", "acv": "Surely he has borne our griefs, and carried our sorrows. Yet we esteemed him stricken, smitten by God, and afflicted.", "anderson": "", "haweis": "", "noyes": "But he bore our diseases, And carried our pains, And we esteemed him stricken from above, Smitten of God, and afflicted.", "webster": "Surely he hath borne our griefs, and carried our sorrows: yet we did esteem him stricken, smitten by God, and afflicted.", "vulgate": "vere languores nostros ipse tulit et dolores nostros ipse portavit et nos putavimus eum quasi leprosum et percussum a Deo et humiliatum;", "brenton": "He bears our sins, and is pained for us: yet we accounted him to be in trouble, and in suffering, and in affliction."}}, {"v": 5, "ref": "53:5", "o": "וְ/הוּא֙ מְחֹלָ֣ל מִ/פְּשָׁעֵ֔/נוּ מְדֻכָּ֖א מֵ/עֲוֺנֹתֵ֑י/נוּ מוּסַ֤ר שְׁלוֹמֵ֨/נוּ֙ עָלָ֔י/ו וּ/בַ/חֲבֻרָת֖/וֹ נִרְפָּא לָֽ/נוּ", "en": {"kjv": "But he was wounded for our transgressions, he was bruised for our iniquities: the chastisement of our peace was upon him; and with his stripes we are healed.", "web": "But he was pierced for our transgressions. He was crushed for our iniquities. The punishment that brought our peace was on him; and by his wounds we are healed.", "bsb": "But He was pierced for our transgressions, He was crushed for our iniquities; the punishment that brought us peace was upon Him, and by His stripes we are healed.", "asv": "But he was wounded for our transgressions, he was bruised for our iniquities; the chastisement of our peace was upon him; and with his stripes we are healed.", "ylt": "And he is pierced for our transgressions, Bruised for our iniquities, The chastisement of our peace is on him, And by his bruise there is healing to us.", "dra": "But he was wounded for our iniquities, he was bruised for our sins: the chastisement of our peace was upon him, and by his bruises we are healed.", "bbe": "But it was for our sins he was wounded, and for our evil doings he was crushed: he took the punishment by which we have peace, and by his wounds we are made well.", "geneva": "But hee was wounded for our transgressions, hee was broken for our iniquities: the chastisement of our peace was vpon him, and with his stripes we are healed.", "wycliffe": "Forsothe he was woundid for oure wickidnessis, he was defoulid for oure greet trespassis; the lernyng of oure pees was on hym, and we ben maad hool bi his wannesse.", "rotherham": "Yet, he, was pierced for transgressions that were ours, was crushed for iniquities that were ours,—the chastisement for our well-being, was upon him, And by his stripes, there is healing for us.", "darby": "But he was wounded for our transgressions, he was bruised for our iniquities; the chastisement of our peace was upon him, and with his stripes we are healed.", "twenty": "", "jps": "But he was wounded because of our transgressions, he was crushed because of our iniquities: the chastisement of our welfare was upon him, and with his stripes we were healed.", "acv": "But he was wounded for our transgressions. He was bruised for our iniquities. The chastisement of our peace was upon him, and with his stripes we are healed.", "anderson": "", "haweis": "", "noyes": "But he was wounded for our transgressions; He was bruised for our iniquities; For our peace was the chastisement upon him, And by his stripes are we healed.", "webster": "But he [was] wounded for our transgression, [he was] bruised for our iniquities: the chastisement of our peace [was] upon him; and with his stripes we are healed.", "vulgate": "ipse autem vulneratus est propter iniquitates nostras adtritus est propter scelera nostra disciplina pacis nostrae super eum et livore eius sanati sumus;", "brenton": "But he was wounded on account of our sins, and was bruised because of our iniquities: the chastisement of our peace was upon him; and by his bruises we were healed."}}, {"v": 6, "ref": "53:6", "o": "כֻּלָּ֨/נוּ֙ כַּ/צֹּ֣אן תָּעִ֔ינוּ אִ֥ישׁ לְ/דַרְכּ֖/וֹ פָּנִ֑ינוּ וַֽ/יהוָה֙ הִפְגִּ֣יעַ בּ֔/וֹ אֵ֖ת עֲוֺ֥ן כֻּלָּֽ/נוּ", "en": {"kjv": "All we like sheep have gone astray; we have turned every one to his own way; and the Lord hath laid on him the iniquity of us all.", "web": "All we like sheep have gone astray. Everyone has turned to his own way; and Yahweh has laid on him the iniquity of us all.", "bsb": "We all like sheep have gone astray, each one has turned to his own way; and the LORD has laid upon Him the iniquity of us all.", "asv": "All we like sheep have gone astray; we have turned every one to his own way; and Jehovah hath laid on him the iniquity of us all.", "ylt": "All of us like sheep have wandered, Each to his own way we have turned, And Jehovah hath caused to meet on him, The punishment of us all.", "dra": "All we like sheep have gone astray, every one hath turned aside into his own way: and the Lord hath laid on him the iniquity of us all.", "bbe": "We all went wandering like sheep; going every one of us after his desire; and the Lord put on him the punishment of us all.", "geneva": "All we like sheepe haue gone astraye: wee haue turned euery one to his owne way, and the Lord hath layed vpon him the iniquitie of vs all.", "wycliffe": "Alle we erriden as scheep, ech man bowide in to his owne weie, and the Lord puttide in hym the wickidnesse of vs alle.", "rotherham": "We all, like sheep, had gone astray, Every man—to his way, had we burned,—And Yahweh! caused to light upon him The guilt of, us all!", "darby": "All we like sheep have gone astray, we have turned every one to his own way; and Jehovah hath laid upon him the iniquity of us all.", "twenty": "", "jps": "All we like sheep did go astray, we turned every one to his own way; and HaShem hath made to light on him the iniquity of us all.", "acv": "All we like sheep have gone astray. We have turned every one to his own way, and Jehovah has laid on him the iniquity of us all.", "anderson": "", "haweis": "", "noyes": "All we, like sheep, were going astray; We turned every one to his own way, And Jehovah laid upon him the iniquity of us all.", "webster": "All we like sheep have gone astray; we have turned every one to his own way; and the LORD hath laid on him the iniquity of us all.", "vulgate": "omnes nos quasi oves erravimus unusquisque in viam suam declinavit et Dominus posuit in eo iniquitatem omnium nostrum;", "brenton": "All we as sheep have gone astray; every one has gone astray in his way; and the Lord gave him up for our sins."}}, {"v": 7, "ref": "53:7", "o": "נִגַּ֨שׂ וְ/ה֣וּא נַעֲנֶה֮ וְ/לֹ֣א יִפְתַּח פִּי/ו֒ כַּ/שֶּׂה֙ לַ/טֶּ֣בַח יוּבָ֔ל וּ/כְ/רָחֵ֕ל לִ/פְנֵ֥י גֹזְזֶ֖י/הָ נֶאֱלָ֑מָה וְ/לֹ֥א יִפְתַּ֖ח פִּֽי/ו", "en": {"kjv": "He was oppressed, and he was afflicted, yet he opened not his mouth: he is brought as a lamb to the slaughter, and as a sheep before her shearers is dumb, so he openeth not his mouth.", "web": "He was oppressed, yet when he was afflicted he didn’t open his mouth. As a lamb that is led to the slaughter, and as a sheep that before its shearers is mute, so he didn’t open his mouth.", "bsb": "He was oppressed and afflicted, yet He did not open His mouth. He was led like a lamb to the slaughter, and as a sheep before her shearers is silent, so He did not open His mouth.", "asv": "He was oppressed, yet when he was afflicted he opened not his mouth; as a lamb that is led to the slaughter, and as a sheep that before its shearers is dumb, so he opened not his mouth.", "ylt": "It hath been exacted, and he hath answered, And he openeth not his mouth, As a lamb to the slaughter he is brought, And as a sheep before its shearers is dumb, And he openeth not his mouth.", "dra": "He was offered because it was his own will, and he opened not his mouth: he shall be led as a sheep to the slaughter, and shall be dumb as a lamb before his shearer, and he shall not open his mouth.", "bbe": "Men were cruel to him, but he was gentle and quiet; as a lamb taken to its death, and as a sheep before those who take her wool makes no sound, so he said not a word.", "geneva": "Hee was oppressed and he was afflicted, yet did he not open his mouth: hee is brought as a sheepe to the slaughter, and as a sheepe before her shearer is dumme, so he openeth not his mouth.", "wycliffe": "He was offrid, for he wolde, and he openyde not his mouth; as a scheep he schal be led to sleyng, and he schal be doumb as a lomb bifore hym that clippith it, and he schal not opene his mouth.", "rotherham": "Hard pressed—yet, he, humbled himself Nor opened his mouth—As, a lamb, to the slaughter, is led, And, as a sheep, before her shearers, is dumb—Nor opened his mouth.", "darby": "He was oppressed, and he was afflicted, but he opened not his mouth; he was led as a lamb to the slaughter, and was as a sheep dumb before her shearers, and he opened not his mouth.", "twenty": "", "jps": "He was oppressed, though he humbled himself and opened not his mouth; as a lamb that is led to the slaughter, and as a sheep that before her shearers is dumb; yea, he opened not his mouth.", "acv": "He was oppressed, yet when he was afflicted he opened not his mouth. As a lamb that is led to the slaughter, and as a sheep that is mute before its shearers, so he opened not his mouth.", "anderson": "", "haweis": "", "noyes": "He was oppressed, that was already afflicted. Yet he opened not his mouth; As a lamb that is led to the slaughter, And as a sheep before her shearers is dumb, He opened not his mouth.", "webster": "He was oppressed, and he was afflicted, yet he opened not his mouth; he is brought as a lamb to the slaughter, and as a sheep before her shearers is dumb, so he opened not his mouth.", "vulgate": "oblatus est quia ipse voluit et non aperuit os suum sicut ovis ad occisionem ducetur et quasi agnus coram tondente obmutescet et non aperiet os suum;", "brenton": "And he, because of his affliction, opens not his mouth: he was led as a sheep to the slaughter, and as a lamb before the shearer is dumb, so he opens not his mouth."}}, {"v": 8, "ref": "53:8", "o": "מֵ/עֹ֤צֶר וּ/מִ/מִּשְׁפָּט֙ לֻקָּ֔ח וְ/אֶת דּוֹר֖/וֹ מִ֣י יְשׂוֹחֵ֑חַ כִּ֤י נִגְזַר֙ מֵ/אֶ֣רֶץ חַיִּ֔ים מִ/פֶּ֥שַׁע עַמִּ֖/י נֶ֥גַע לָֽ/מוֹ", "en": {"kjv": "He was taken from prison and from judgment: and who shall declare his generation? for he was cut off out of the land of the living: for the transgression of my people was he stricken.", "web": "He was taken away by oppression and judgment; and as for his generation, who considered that he was cut off out of the land of the living and stricken for the disobedience of my people?", "bsb": "By oppression and judgment He was taken away, and who can recount His descendants? For He was cut off from the land of the living; He was stricken for the transgression of My people.", "asv": "By oppression and judgment he was taken away; and as for his generation, who among them considered that he was cut off out of the land of the living for the transgression of my people to whom the stroke was due?", "ylt": "By restraint and by judgment he hath been taken, And of his generation who doth meditate, That he hath been cut off from the land of the living? By the transgression of My people he is plagued,", "dra": "He was taken away from distress, and from judgment: who shall declare his generation? because he is cut off out of the land of the living: for the wickedness of my people have I struck him.", "bbe": "They took away from him help and right, and who gave a thought to his fate? for he was cut off from the land of the living: he came to his death for the sin of my people.", "geneva": "Hee was taken out from prison, and from iudgement: and who shall declare his age? for he was cut out of the lande of the liuing: for the transgression of my people was he plagued.", "wycliffe": "He is takun awey fro angwisch and fro doom; who schal telle out the generacioun of hym? For he was kit doun fro the lond of lyueris. Y smoot hym for the greet trespas of my puple.", "rotherham": "By constraint and by sentence, was he taken away, And of his age, who considered That he was cut off out of the land of the living, For my people’s transgression, did the stroke fall on him?", "darby": "He was taken from oppression and from judgment; and who shall declare his generation? for he was cut off out of the land of the living; for the transgression of my people was he stricken.", "twenty": "", "jps": "By oppression and judgment he was taken away, and with his generation who did reason? for he was cut off out of the land of the living, for the transgression of my people to whom the stroke was due.", "acv": "In his humiliation his justice was taken away. And as for his generation, who considered that he was cut off out of the land of the living for the transgression of my people, to whom the stroke was due?", "anderson": "", "haweis": "", "noyes": "By oppression and punishment he was taken away, And who in his generation would consider That he was cut off from the land of the living, That for the transgression of my people he was smitten?", "webster": "He was taken from prison and from judgment: and who shall declare his generation? for he was cut off from the land of the living: for the transgression of my people was he stricken.", "vulgate": "de angustia et de iudicio sublatus est generationem eius quis enarrabit quia abscisus est de terra viventium propter scelus populi mei percussit eum;", "brenton": "In his humiliation his judgment was taken away: who shall declare his generation? for his life is taken away from the earth: because of the iniquities of my people he was led to death."}}, {"v": 9, "ref": "53:9", "o": "וַ/יִּתֵּ֤ן אֶת רְשָׁעִים֙ קִבְר֔/וֹ וְ/אֶת עָשִׁ֖יר בְּ/מֹתָ֑י/ו עַ֚ל לֹא חָמָ֣ס עָשָׂ֔ה וְ/לֹ֥א מִרְמָ֖ה בְּ/פִֽי/ו", "en": {"kjv": "And he made his grave with the wicked, and with the rich in his death; because he had done no violence, neither was any deceit in his mouth.", "web": "They made his grave with the wicked, and with a rich man in his death; although he had done no violence, neither was any deceit in his mouth.", "bsb": "He was assigned a grave with the wicked, and with a rich man in His death, although He had done no violence, nor was any deceit in His mouth.", "asv": "And they made his grave with the wicked, and with a rich man in his death; although he had done no violence, neither was any deceit in his mouth.", "ylt": "And it appointeth with the wicked his grave, And with the rich are his high places, Because he hath done no violence, Nor is deceit in his mouth.", "dra": "And he shall give the ungodly for his burial, and the rich for his death: because he hath done no iniquity, neither was there deceit in his mouth.", "bbe": "And they put his body into the earth with sinners, and his last resting-place was with the evil-doers, though he had done no wrong, and no deceit was in his mouth.", "geneva": "And he made his graue with the wicked, and with the riche in his death, though hee had done no wickednesse, neither was any deceite in his mouth.", "wycliffe": "And he schal yyue vnfeithful men for biriyng, and riche men for his deth; for he dide not wickidnesse, nether gile was in his mouth;", "rotherham": "And, appointed with lawless men, was his grave, And with the wicked, his tomb,—Though no violence, had he done, Nor was guile in his mouth.", "darby": "And [men] appointed his grave with the wicked, but he was with the rich in his death, because he had done no violence, neither was there guile in his mouth.", "twenty": "", "jps": "And they made his grave with the wicked, and with the rich his tomb; although he had done no violence, neither was any deceit in his mouth.'", "acv": "And they made his grave with the wicked, and with a rich man in his death. Although he had done no violence, nor was any deceit in his mouth.", "anderson": "", "haweis": "", "noyes": "His grave was appointed with the wicked, And with the rich man was his sepulchre, Although he had done no injustice, And there was no deceit in his mouth.", "webster": "And he made his grave with the wicked, and with the rich in his death: because he had done no violence, neither [was any] deceit in his mouth.", "vulgate": "et dabit impios pro sepultura et divitem pro morte sua eo quod iniquitatem non fecerit neque dolus fuerit in ore eius;", "brenton": "And I will give the wicked for his burial, and the rich for his death; for he practised no iniquity, nor craft with his mouth."}}, {"v": 10, "ref": "53:10", "o": "וַ/יהוָ֞ה חָפֵ֤ץ דַּכְּא/וֹ֙ הֶֽחֱלִ֔י אִם תָּשִׂ֤ים אָשָׁם֙ נַפְשׁ֔/וֹ יִרְאֶ֥ה זֶ֖רַע יַאֲרִ֣יךְ יָמִ֑ים וְ/חֵ֥פֶץ יְהוָ֖ה בְּ/יָד֥/וֹ יִצְלָֽח", "en": {"kjv": "Yet it pleased the Lord to bruise him; he hath put him to grief: when thou shalt make his soul an offering for sin, he shall see his seed, he shall prolong his days, and the pleasure of the Lord shall prosper in his hand.", "web": "Yet it pleased Yahweh to bruise him. He has caused him to suffer. When you make his soul an offering for sin, he shall see his seed. He shall prolong his days, and the pleasure of Yahweh shall prosper in his hand.", "bsb": "Yet it was the LORD’s will to crush Him and to cause Him to suffer; and when His soul is made a guilt offering, He will see His offspring, He will prolong His days, and the good pleasure of the LORD will prosper in His hand.", "asv": "Yet it pleased Jehovah to bruise him; he hath put him to grief: when thou shalt make his soul an offering for sin, he shall see his seed, he shall prolong his days, and the pleasure of Jehovah shall prosper in his hand.", "ylt": "And Jehovah hath delighted to bruise him, He hath made him sick, If his soul doth make an offering for guilt, He seeth seed--he prolongeth days, And the pleasure of Jehovah in his hand doth prosper.", "dra": "And the Lord was pleased to bruise him in infirmity: if he shall lay down his life for sin, he shall see a longlived seed, and the will of the Lord shall be prosperous in his hand.", "bbe": "And the Lord was pleased ... see a seed, long life, ... will do well in his hand. ...", "geneva": "Yet the Lord would breake him, and make him subiect to infirmities: when hee shall make his soule an offring for sinne, he shall see his seede and shall prolong his dayes, and the will of the Lord shall prosper in his hand.", "wycliffe": "and the Lord wolde defoule hym in sikenesse. If he puttith his lijf for synne, he schal se seed long durynge, and the wille of the Lord schal be dressid in his hond.", "rotherham": "Yet, Yahweh, purposed to bruise him, He laid on him sickness:—If his soul become an offering for guilt, He shall see a seed, He shall prolong his days,—And the purpose of Yahweh, in his hand, shall prosper:", "darby": "Yet it pleased Jehovah to bruise him; he hath subjected [him] to suffering. When thou shalt make his soul an offering for sin, he shall see a seed, he shall prolong [his] days, and the pleasure of Jehovah shall prosper in his hand.", "twenty": "", "jps": "Yet it pleased HaShem to crush him by disease; to see if his soul would offer itself in restitution, that he might see his seed, prolong his days, and that the purpose of HaShem might prosper by his hand:", "acv": "Yet it pleased Jehovah to bruise him. He has put him to grief. When thou shall make his soul an offering for sin, he shall see his seed. He shall prolong his days, and the pleasure of Jehovah shall prosper in his hand.", "anderson": "", "haweis": "", "noyes": "It pleased Jehovah severely to bruise him; But when he hath made his life a sacrifice for sin, He shall see posterity; he shall prolong his days, And the pleasure of Jehovah shall prosper in his hand.", "webster": "Yet it pleased the LORD to bruise him; he hath put [him] to grief: when thou shalt make his soul an offering for sin, he shall see [his] seed, he shall prolong [his] days, and the pleasure of the LORD shall prosper in his hand.", "vulgate": "et Dominus voluit conterere eum in infirmitate si posuerit pro peccato animam suam videbit semen longevum et voluntas Domini in manu eius dirigetur;", "brenton": "The Lord also is pleased to purge him from his stroke. If ye can give an offering for sin, your soul shall see a long-lived seed:"}}, {"v": 11, "ref": "53:11", "o": "מֵ/עֲמַ֤ל נַפְשׁ/וֹ֙ יִרְאֶ֣ה יִשְׂבָּ֔ע בְּ/דַעְתּ֗/וֹ יַצְדִּ֥יק צַדִּ֛יק עַבְדִּ֖/י לָֽ/רַבִּ֑ים וַ/עֲוֺנֹתָ֖/ם ה֥וּא יִסְבֹּֽל", "en": {"kjv": "He shall see of the travail of his soul, and shall be satisfied: by his knowledge shall my righteous servant justify many; for he shall bear their iniquities.", "web": "After the suffering of his soul, he will see the light and be satisfied. My righteous servant will justify many by the knowledge of himself; and he will bear their iniquities.", "bsb": "After the anguish of His soul, He will see the light of life and be satisfied. By His knowledge My righteous Servant will justify many, and He will bear their iniquities.", "asv": "He shall see of the travail of his soul, and shall be satisfied: by the knowledge of himself shall my righteous servant justify many; and he shall bear their iniquities.", "ylt": "Of the labour of his soul he seeth--he is satisfied, Through his knowledge give righteousness Doth the righteous one, My servant, to many, And their iniquities he doth bear.", "dra": "Because his soul hath laboured, he shall see and be filled: by his knowledge shall this my just servant justify many, and he shall bear their iniquities.", "bbe": "... made clear his righteousness before men ... had taken their sins on himself.", "geneva": "Hee shall see of the trauaile of his soule, and shall be satisfied: by his knowledge shall my righteous seruant iustifie many: for hee shall beare their iniquities.", "wycliffe": "For that that his soule trauelide, he schal se, and schal be fillid. Thilke my iust seruaunt schal iustifie many men in his kunnyng, and he schal bere the wickidnessis of hem.", "rotherham": "Of the travail of his soul, shall he see He shall be satisfied with his knowledge, A setting right when set right himself, shall my Servant win for the Many, Since of their iniquities, he, taketh the burden.", "darby": "He shall see of [the fruit of] the travail of his soul, [and] shall be satisfied: by his knowledge shall my righteous servant instruct many in righteousness; and he shall bear their iniquities.", "twenty": "", "jps": "Of the travail of his soul he shall see to the full, even My servant, who by his knowledge did justify the Righteous One to the many, and their iniquities he did bear.", "acv": "He shall see of the travail of his soul, and shall be satisfied. By the knowledge of himself shall my righteous servant justify many, and he shall bear their iniquities.", "anderson": "", "haweis": "", "noyes": "Free from his sorrows, he shall see and be satisfied; By his knowledge shall my righteous servant lead many to righteousness, And he shall bear their iniquities.", "webster": "He shall see of the travail of his soul, [and] shall be satisfied: by his knowledge shall my righteous servant justify many; for he shall bear their iniquities.", "vulgate": "pro eo quod laboravit anima eius videbit et saturabitur in scientia sua iustificabit ipse iustus servus meus multos et iniquitates eorum ipse portabit;", "brenton": "the Lord also is pleased to take away from the travail of his soul, to shew him light, and to form him with understanding; to justify the just one who serves many well; and he shall bear their sins."}}, {"v": 12, "ref": "53:12", "o": "לָ/כֵ֞ן אֲחַלֶּק ל֣/וֹ בָ/רַבִּ֗ים וְ/אֶת עֲצוּמִים֮ יְחַלֵּ֣ק שָׁלָל֒ תַּ֗חַת אֲשֶׁ֨ר הֶעֱרָ֤ה לַ/מָּ֨וֶת֙ נַפְשׁ֔/וֹ וְ/אֶת פֹּשְׁעִ֖ים נִמְנָ֑ה וְ/הוּא֙ חֵטְא רַבִּ֣ים נָשָׂ֔א וְ/לַ/פֹּשְׁעִ֖ים יַפְגִּֽיעַ", "en": {"kjv": "Therefore will I divide him a portion with the great, and he shall divide the spoil with the strong; because he hath poured out his soul unto death: and he was numbered with the transgressors; and he bare the sin of many, and made intercession for the transgressors.", "web": "Therefore will I divide him a portion with the great, and he shall divide the plunder with the strong; because he poured out his soul to death, and was numbered with the transgressors; yet he bore the sin of many, and made intercession for the transgressors.", "bsb": "Therefore I will allot Him a portion with the great, and He will divide the spoils with the strong, because He has poured out His life unto death, and He was numbered with the transgressors. Yet He bore the sin of many and made intercession for the transgressors.", "asv": "Therefore will I divide him a portion with the great, and he shall divide the spoil with the strong; because he poured out his soul unto death, and was numbered with the transgressors: yet he bare the sin of many, and made intercession for the transgressors.", "ylt": "Therefore I give a portion to him among the many, And with the mighty he apportioneth spoil, Because that he exposed to death his soul, And with transgressors he was numbered, And he the sin of many hath borne, And for transgressors he intercedeth.", "dra": "Therefore will I distribute to him very many, and he shall divide the spoils of the strong, because he hath delivered his soul unto death, and was reputed with the wicked: and he hath borne the sins of many, and hath prayed for the transgressors.", "bbe": "For this cause he will have a heritage with the great, and he will have a part in the goods of war with the strong, because he gave up his life, and was numbered with the evil-doers; taking on himself the sins of the people, and making prayer for the wrongdoers.", "geneva": "Therefore will I giue him a portion with the great, and he shall deuide the spoyle with the strong, because hee hath powred out his soule vnto death: and he was counted with the transgressers, and he bare the sinne of many, and prayed for the trespassers.", "wycliffe": "Therfor Y schal yelde, ethir dele, to hym ful many men, and he schal departe the spuilis of the stronge feendis; for that that he yaf his lijf in to deth, and was arettid with felenouse men; and he dide a wei the synne of many men, and he preiede for trespassouris.", "rotherham": "Therefore, will I give him a portion in the great, And the strong, shall he apportion as spoil, Because he poured out, to death his own soul, And with transgressors, let himself be numbered,—Yea, he, the sin of Many, bare, And for transgressors, interposeth.", "darby": "Therefore will I assign him a portion with the great, and he shall divide the spoil with the strong: because he hath poured out his soul unto death, and was reckoned with the transgressors; and he bore the sin of many, and made intercession for the transgressors.", "twenty": "", "jps": "Therefore will I divide him a portion among the great, and he shall divide the spoil with the mighty; because he bared his soul unto death, and was numbered with the transgressors; yet he bore the sin of many, and made intercession for the transgressors.", "acv": "Therefore I will divide him a portion with the great, and he shall divide the spoil with the strong, because he poured out his soul to death, and was numbered with the transgressors. Yet he bore the sin of many, and made intercession for the transgressors.", "anderson": "", "haweis": "", "noyes": "Therefore will I give him his portion with the mighty, And with heroes shall he divide the spoil, Because he poured out his soul unto death, And was numbered with transgressors; Because he bore the sin of many, And made intercession for transgressors.", "webster": "Therefore I will divide to him [a portion] with the great, and he shall divide the spoil with the strong; because he hath poured out his soul to death: and he was numbered with the transgressors; and he bore the sin of many, and made intercession for the transgressors.", "vulgate": "ideo dispertiam ei plurimos et fortium dividet spolia pro eo quod tradidit in morte animam suam et cum sceleratis reputatus est et ipse peccatum multorum tulit et pro transgressoribus rogavit;", "brenton": "Therefore he shall inherit many, and he shall divide the spoils of the mighty; because his soul was delivered to death: and he was numbered among the transgressors; and he bore the sins of many, and was delivered because of their iniquities."}}]}, {"c": 54, "verses": [{"v": 1, "ref": "54:1", "o": "רָנִּ֥י עֲקָרָ֖ה לֹ֣א יָלָ֑דָה פִּצְחִ֨י רִנָּ֤ה וְ/צַהֲלִי֙ לֹא חָ֔לָה כִּֽי רַבִּ֧ים בְּֽנֵי שׁוֹמֵמָ֛ה מִ/בְּנֵ֥י בְעוּלָ֖ה אָמַ֥ר יְהוָֽה", "en": {"kjv": "Sing, O barren, thou that didst not bear; break forth into singing, and cry aloud, thou that didst not travail with child: for more are the children of the desolate than the children of the married wife, saith the Lord.", "web": "“Sing, barren, you who didn’t bear; break out into singing, and cry aloud, you who did not travail with child: for more are the children of the desolate than the children of the married wife,” says Yahweh.", "bsb": "“Shout for joy, O barren woman, who bears no children; break forth in song and cry aloud, you who have never travailed; because more are the children of the desolate woman than of her who has a husband,” says the LORD.", "asv": "Sing, O barren, thou that didst not bear; break forth into singing, and cry aloud, thou that didst not travail with child: for more are the children of the desolate than the children of the married wife, saith Jehovah.", "ylt": "Sing, O barren, she hath not borne! Break forth with singing, and cry aloud, She hath not brought forth! For more are the sons of the desolate, Than the sons of the married one, said Jehovah.", "dra": "Give praise, O thou barren, that bearest not: sing forth praise, and make a joyful noise, thou that didst not travail with child: for many are the children of the desolate, more than of her that hath a husband, saith the Lord.", "bbe": "Let your voice be loud in song, O woman without children; make melody and sounds of joy, you who did not give birth: for the children of her who had no husband are more than those of the married wife, says the Lord.", "geneva": "Rejoice, O barren that diddest not beare: breake forth into ioy and reioyce, thou that diddest not trauaile with childe: for the desolate hath moe children then the married wife, sayeth the Lord.", "wycliffe": "Thou bareyn, that childist not, herie; thou that childist not, synge heriyng, and make ioie; for whi many sones ben of the forsakun `womman more than of hir that hadde hosebonde, seith the Lord.", "rotherham": "Shout in triumph, O barren one, Who hadst not borne,—Break forth into shouts of triumph—and trill thy voice, Who hadst not travailed in birth, For, more, are the children of the Desolate Than the children of Her who had the husband, Saith Yahweh.", "darby": "Exult, thou barren, that didst not bear; break forth into singing, and shout for joy, thou that didst not travail with child: for more are the children of the desolate than the children of the married wife, saith Jehovah.", "twenty": "", "jps": "Sing, O barren, thou that didst not bear, break forth into singing, and cry aloud, thou that didst not travail; for more are the children of the desolate than the children of the married wife, saith HaShem.", "acv": "Sing, O barren, thou who did not bear. Break forth into singing, and cry aloud, thou who did not travail with child. For more are the sons of the desolate than the sons of the married woman, says Jehovah.", "anderson": "", "haweis": "", "noyes": "Sing, O thou barren, that didst not hear! Break forth into singing, and shout for joy, thou that wast not in travail! For more are the children of the desolate Than of the married woman, saith Jehovah.", "webster": "Sing, O barren, thou [that] didst not bear; break forth into singing, and cry aloud, thou [that] didst not travail with child: for more [are] the children of the desolate than the children of the married wife, saith the LORD.", "vulgate": "lauda sterilis quae non paris decanta laudem et hinni quae non pariebas quoniam multi filii desertae magis quam eius quae habebat virum dicit Dominus;", "brenton": "Rejoice, thou barren that bearest not; break forth and cry, thou that dost not travail: for more are the children of the desolate than of her that has a husband: for the Lord has said,"}}, {"v": 2, "ref": "54:2", "o": "הַרְחִ֣יבִי מְק֣וֹם אָהֳלֵ֗/ךְ וִ/ירִיע֧וֹת מִשְׁכְּנוֹתַ֛יִ/ךְ יַטּ֖וּ אַל תַּחְשֹׂ֑כִי הַאֲרִ֨יכִי֙ מֵֽיתָרַ֔יִ/ךְ וִ/יתֵדֹתַ֖יִ/ךְ חַזֵּֽקִי", "en": {"kjv": "Enlarge the place of thy tent, and let them stretch forth the curtains of thine habitations: spare not, lengthen thy cords, and strengthen thy stakes;", "web": "“Enlarge the place of your tent, and let them stretch out the curtains of your habitations; don’t spare: lengthen your cords, and strengthen your stakes.", "bsb": "“Enlarge the site of your tent, stretch out the curtains of your dwellings, do not hold back. Lengthen your ropes and drive your stakes in deep.", "asv": "Enlarge the place of thy tent, and let them stretch forth the curtains of thy habitations; spare not: lengthen thy cords, and strengthen thy stakes.", "ylt": "Enlarge the place of thy tent, And the curtains of thy tabernacles they stretch out, Restrain not--lengthen thy cords, And thy pins make strong.", "dra": "Enlarge the place of thy tent, and stretch out the skins of thy tabernacles, spare not: lengthen thy cords, and strengthen thy stakes.", "bbe": "Make wide the place of your tent, and let the curtains of your house be stretched out without limit: make your cords long, and your tent-pins strong.", "geneva": "Enlarge the place of thy tents, and let them spread out the curtains of thine habitations: spare not, stretch out thy cords and make fast thy stakes.", "wycliffe": "Alarge thou the place of thi tente, and stretche forth the skynnes of thi tabernaclis; spare thou not, make longe thi roopis, and make sad thi nailis.", "rotherham": "Enlarge the space of thy tent And the curtains of thy habitations, let them spread forth do not spare,—Lengthen thy cords, And thy tent-pins, make thou fast;", "darby": "Enlarge the place of thy tent, and let them stretch forth the curtains of thy habitations: spare not, lengthen thy cords, and strengthen thy stakes.", "twenty": "", "jps": "Enlarge the place of thy tent, and let them stretch forth the curtains of thy habitations, spare not; lengthen thy cords, and strengthen thy stakes.", "acv": "Enlarge the place of thy tent, and let them stretch forth the curtains of thy habitations. Spare not. Lengthen thy cords, and strengthen thy stakes.", "anderson": "", "haweis": "", "noyes": "Enlarge the place of thy tent, And let the canopy of thy habitation be extended! Spare not; lengthen thy cords, And make fast thy stakes!", "webster": "Enlarge the place of thy tent, and let them extend the curtains of thy habitations: spare not, lengthen thy cords, and strengthen thy stakes;", "vulgate": "dilata locum tentorii tui et pelles tabernaculorum tuorum extende ne parcas longos fac funiculos tuos et clavos tuos consolida;", "brenton": "Enlarge the place of thy tent, and of thy curtains: fix the pins, spare not, lengthen thy cords, and strengthen thy pins;"}}, {"v": 3, "ref": "54:3", "o": "כִּי יָמִ֥ין וּ/שְׂמֹ֖אול תִּפְרֹ֑צִי וְ/זַרְעֵ/ךְ֙ גּוֹיִ֣ם יִירָ֔שׁ וְ/עָרִ֥ים נְשַׁמּ֖וֹת יוֹשִֽׁיבוּ", "en": {"kjv": "For thou shalt break forth on the right hand and on the left; and thy seed shall inherit the Gentiles, and make the desolate cities to be inhabited.", "web": "For you shall spread out on the right hand and on the left; and your seed shall possess the nations, and make the desolate cities to be inhabited.", "bsb": "For you will spread out to the right and left; your descendants will dispossess the nations and inhabit the desolate cities.", "asv": "For thou shalt spread abroad on the right hand and on the left; and thy seed shall possess the nations, and make the desolate cities to be inhabited.", "ylt": "For right and left thou breakest forth, And thy seed doth nations possess,", "dra": "For thou shalt pass on to the right hand, and to the left: and thy seed shall inherit the Gentiles, and shall inhabit the desolate cities.", "bbe": "For I will make wide your limits on the right hand and on the left; and your seed will take the nations for a heritage, and make the waste towns full of people.", "geneva": "For thou shalt increase on the right hande and on the left, and thy seede shall possesse the Gentiles, and dwell in the desolate cities.", "wycliffe": "For thou schalt perse to the riytside and to the leftside; and thi seed schal enherite hethene men, and schal dwelle in forsakun citees.", "rotherham": "For, on the right hand and on the left, shalt thou break forth,—And thy seed, shall of the nations, take possession, And forsaken cities, shall they cause to be inhabited.", "darby": "For thou shalt spread abroad on the right hand and on the left; and thy seed shall possess nations, and they shall make desolate cities to be inhabited.", "twenty": "", "jps": "For thou shalt spread abroad on the right hand and on the left; and thy seed shall possess the nations, and make the desolate cities to be inhabited.", "acv": "For thou shall spread abroad on the right hand and on the left. And thy seed shall possess the nations, and make the desolate cities to be inhabited.", "anderson": "", "haweis": "", "noyes": "For on the right hand and on the left shalt thou burst forth with increase; And thy posterity shall inherit the nations, And people the desolate cities.", "webster": "For thou shalt break forth on the right hand and on the left; and thy seed shall inherit the Gentiles, and make the desolate cities to be inhabited.", "vulgate": "ad dexteram enim et ad levam penetrabis et semen tuum gentes hereditabit et civitates desertas inhabitabit;", "brenton": "spread forth thy tent yet to the right and the left: for thy seed shall inherit the Gentiles, and thou shalt make the desolate cities to be inhabited."}}, {"v": 4, "ref": "54:4", "o": "אַל תִּֽירְאִי֙ כִּי לֹ֣א תֵב֔וֹשִׁי וְ/אַל תִּכָּלְמִ֖י כִּ֣י לֹ֣א תַחְפִּ֑ירִי כִּ֣י בֹ֤שֶׁת עֲלוּמַ֨יִ/ךְ֙ תִּשְׁכָּ֔חִי וְ/חֶרְפַּ֥ת אַלְמְנוּתַ֖יִ/ךְ לֹ֥א תִזְכְּרִי עֽוֹד", "en": {"kjv": "Fear not; for thou shalt not be ashamed: neither be thou confounded; for thou shalt not be put to shame: for thou shalt forget the shame of thy youth, and shalt not remember the reproach of thy widowhood any more.", "web": "“Don’t be afraid; for you shall not be ashamed: neither be confounded; for you shall not be disappointed: for you shall forget the shame of your youth; and the reproach of your widowhood you shall remember no more.", "bsb": "Do not be afraid, for you will not be put to shame; do not be intimidated, for you will not be humiliated. For you will forget the shame of your youth and will remember no more the reproach of your widowhood.", "asv": "Fear not; for thou shalt not be ashamed: neither be thou confounded; for thou shalt not be put to shame: for thou shalt forget the shame of thy youth; and the reproach of thy widowhood shalt thou remember no more.", "ylt": "And desolate cities they cause to be inhabited. Fear not, for thou art not ashamed, Nor blush, for thou art not confounded, For the shame of thy youth thou forgettest, And the reproach of thy widowhood Thou dost not remember any more.", "dra": "Fear not, for thou shalt not be confounded, nor blush: for thou shalt not be put to shame, because thou shalt forget the shame of thy youth, and shalt remember no more the reproach of thy widowhood.", "bbe": "Have no fear; for you will not be shamed or without hope: you will not be put to shame, for the shame of your earlier days will go out of your memory, and you will no longer keep in mind the sorrows of your widowed years.", "geneva": "Feare not: for thou shalt not be ashamed, neither shalt thou be confounded: for thou shalt not bee put to shame: yea, thou shalt forget the shame of thy youth, and shalt not remember the reproch of thy widdowhoode any more.", "wycliffe": "Nile thou drede, for thou schal not be schent, nether thou schalt be aschamed. For it schal not schame thee; for thou schalt foryete the schenschipe of thi yongthe, and thou schalt no more thenke on the schenschipe of thi widewehod.", "rotherham": "Do not fear for thou shalt not turn pale, Neither feel disgraced for thou shalt not be put to the blush,—For, the shame of thy youth, shalt thou forget, And the reproach of thy widowhood, shalt thou remember no more;", "darby": "Fear not, for thou shalt not be ashamed; neither be thou confounded, for thou shalt not be put to shame: for thou shalt forget the shame of thy youth, and shalt not remember the reproach of thy widowhood any more.", "twenty": "", "jps": "Fear not, for thou shalt not be ashamed. Neither be thou confounded, for thou shalt not be put to shame; for thou shalt forget the shame of thy youth, and the reproach of thy widowhood shalt thou remember no more.", "acv": "Fear not, for thou shall not be ashamed. Neither be thou confounded, for thou shall not be put to shame. For thou shall forget the shame of thy youth. And the reproach of thy widowhood thou shall remember no more.", "anderson": "", "haweis": "", "noyes": "Fear not, for thou shalt not be confounded; Blush not, for thou shalt not be put to shame. For thou shalt forget the shame of thy youth, And the reproach of thy widowhood thou shalt remember no more.", "webster": "Fear not; for thou shalt not be ashamed: neither be thou confounded; for thou shalt not be put to shame; for thou shalt forget the shame of thy youth, and shalt not remember the reproach of thy widowhood any more.", "vulgate": "noli timere quia non confunderis neque erubescas non enim te pudebit quia confusionis adulescentiae tuae oblivisceris et obprobrii viduitatis tuae non recordaberis amplius;", "brenton": "Fear not, because thou has been put to shame, neither be confounded, because thou was reproached: for thou shalt forget thy former shame, and shalt no more at all remember the reproach of thy widowhood."}}, {"v": 5, "ref": "54:5", "o": "כִּ֤י בֹעֲלַ֨יִ/ךְ֙ עֹשַׂ֔יִ/ךְ יְהוָ֥ה צְבָא֖וֹת שְׁמ֑/וֹ וְ/גֹֽאֲלֵ/ךְ֙ קְד֣וֹשׁ יִשְׂרָאֵ֔ל אֱלֹהֵ֥י כָל הָ/אָ֖רֶץ יִקָּרֵֽא", "en": {"kjv": "For thy Maker is thine husband; the Lord of hosts is his name; and thy Redeemer the Holy One of Israel; The God of the whole earth shall he be called.", "web": "For your Maker is your husband; Yahweh of Armies is his name: and the Holy One of Israel is your Redeemer; the God of the whole earth shall he be called.", "bsb": "For your husband is your Maker— the LORD of Hosts is His name— the Holy One of Israel is your Redeemer; He is called the God of all the earth.", "asv": "For thy Maker is thy husband; Jehovah of hosts is his name: and the Holy One of Israel is thy Redeemer; the God of the whole earth shall he be called.", "ylt": "For thy Maker is thy husband, Jehovah of Hosts is His name, And thy Redeemer is the Holy One of Israel, `God of all the earth,' He is called.", "dra": "For he that made thee shall rule over thee, the Lord of hosts is his name: and thy Redeemer, the Holy One of Israel, shall be called the God of all the earth.", "bbe": "For your Maker is your husband; the Lord of armies is his name: and the Holy One of Israel is he who takes up your cause; he will be named the God of all the earth.", "geneva": "For hee that made thee, is thine husband (whose Name is the Lord of hostes) and thy redeemer the Holy one of Israel, shall be called the God of the whole world.", "wycliffe": "For he that made thee, schal be lord of thee; the Lord of oostis is his name; and thin ayenbiere, the hooli of Israel, schal be clepid God of al erthe.", "rotherham": "For, thy husband, is, thy Maker, Yahweh of hosts, is his Name,—And, thy redeemer, the Holy One of Israel, The God of all the earth, shall he be called.", "darby": "For thy Maker is thy husband: Jehovah of hosts is his name, and thy Redeemer, the Holy One of Israel: theGod of the whole earth shall he be called.", "twenty": "", "jps": "For thy Maker is thy husband, HaShem of hosts is His name; and the Holy One of Israel is thy Redeemer, the G-d of the whole earth shall He be called.", "acv": "For thy maker is thy husband. Jehovah of hosts is his name. And the Holy One of Israel is thy Redeemer. He shall be called the God of the whole earth.", "anderson": "", "haweis": "", "noyes": "For thy husband is thy Maker; Jehovah of hosts is his name. Thy redeemer is the Holy One of Israel; The God of the whole earth shall he be called.", "webster": "For thy maker [is] thy husband; the LORD of hosts [is] his name; and thy Redeemer the Holy One of Israel; The God of the whole earth shall he be called.", "vulgate": "quia dominabitur tui qui fecit te Dominus exercituum nomen eius et redemptor tuus Sanctus Israhel Deus omnis terrae vocabitur;", "brenton": "For it is the Lord that made thee; the Lord of hosts is his name: and he that delivered thee, he is the God of Israel, and shall be called so by the whole earth."}}, {"v": 6, "ref": "54:6", "o": "כִּֽי כְ/אִשָּׁ֧ה עֲזוּבָ֛ה וַ/עֲצ֥וּבַת ר֖וּחַ קְרָאָ֣/ךְ יְהוָ֑ה וְ/אֵ֧שֶׁת נְעוּרִ֛ים כִּ֥י תִמָּאֵ֖ס אָמַ֥ר אֱלֹהָֽיִ/ךְ", "en": {"kjv": "For the Lord hath called thee as a woman forsaken and grieved in spirit, and a wife of youth, when thou wast refused, saith thy God.", "web": "For Yahweh has called you as a wife forsaken and grieved in spirit, even a wife of youth, when she is cast off,” says your God.", "bsb": "For the LORD has called you back, like a wife deserted and wounded in spirit, like the rejected wife of one’s youth,” says your God.", "asv": "For Jehovah hath called thee as a wife forsaken and grieved in spirit, even a wife of youth, when she is cast off, saith thy God.", "ylt": "For, as a woman forsaken and grieved in spirit, Called thee hath Jehovah, Even a youthful wife when she is refused, said thy God.", "dra": "For the Lord hath called thee as a woman forsaken and mourning in spirit, and as a wife cast off from her youth, said thy God.", "bbe": "For the Lord has made you come back to him, like a wife who has been sent away in grief of spirit; for one may not give up the wife of one's early days.", "geneva": "For the Lord hath called thee, being as a woman forsaken, and afflicted in spirite, and as a yong wife when thou wast refused, sayth thy God.", "wycliffe": "For the Lord hath clepid thee as a womman forsakun and morenynge in spirit, and a wijf, `that is cast awei fro yongthe.", "rotherham": "For, like a wife forsaken and grieved in spirit, hath Yahweh called thee,—Even the wife of youthful days, in that thou wast rejected saith thy God.", "darby": "For Jehovah hath called thee as a woman forsaken and grieved in spirit, and as a wife of youth, that hath been refused, saith thyGod.", "twenty": "", "jps": "For HaShem hath called thee as a wife forsaken and grieved in spirit; and a wife of youth, can she be rejected? saith thy G-d.", "acv": "For Jehovah has called thee as a wife forsaken and grieved in spirit, even a wife of youth when she is cast off, says thy God.", "anderson": "", "haweis": "", "noyes": "For as a woman forsaken, and deeply afflicted, hath Jehovah recalled thee, And as a wife wedded in youth, that hath been rejected, saith thy God.", "webster": "For the LORD hath called thee as a woman forsaken and grieved in spirit, and a wife of youth, when thou wast refused, saith thy God.", "vulgate": "quia ut mulierem derelictam et maerentem spiritu vocavit te Dominus et uxorem ab adulescentia abiectam dixit Deus tuus;", "brenton": "The Lord has not called thee as a deserted and faint-hearted woman, nor as a woman hated from her youth, saith thy God."}}, {"v": 7, "ref": "54:7", "o": "בְּ/רֶ֥גַע קָטֹ֖ן עֲזַבְתִּ֑י/ךְ וּ/בְ/רַחֲמִ֥ים גְּדֹלִ֖ים אֲקַבְּצֵֽ/ךְ", "en": {"kjv": "For a small moment have I forsaken thee; but with great mercies will I gather thee.", "web": "“For a small moment have I forsaken you; but with great mercies will I gather you.", "bsb": "“For a brief moment I forsook you, but with great compassion I will bring you back.", "asv": "For a small moment have I forsaken thee; but with great mercies will I gather thee.", "ylt": "In a small moment I have forsaken thee, And in great mercies I do gather thee,", "dra": "For a small moment have I forsaken thee, but with great mercies will I gather thee.", "bbe": "For a short time I gave you up; but with great mercies I will take you back again.", "geneva": "For a litle while haue I forsaken thee, but with great compassion will I gather thee.", "wycliffe": "Thi Lord God seide, At a poynt in litil tyme Y forsook thee, and Y schal gadere thee togidere in greete merciful doyngis.", "rotherham": "For a small moment, I forsook thee,—But, with abounding compassions, do I embrace thee:", "darby": "For a small moment have I forsaken thee; but with great mercies will I gather thee.", "twenty": "", "jps": "For a small moment have I forsaken thee; but with great compassion will I gather thee.", "acv": "For a small moment I have forsaken thee, but with great mercies I will gather thee.", "anderson": "", "haweis": "", "noyes": "For a little moment I have forsaken thee, But with great mercy will I gather thee.", "webster": "For a small moment have I forsaken thee; but with great mercies will I gather thee.", "vulgate": "ad punctum in modico dereliqui te et in miserationibus magnis congregabo te;", "brenton": "For a little while I left thee: but with great mercy will I have compassion upon thee."}}, {"v": 8, "ref": "54:8", "o": "בְּ/שֶׁ֣צֶף קֶ֗צֶף הִסְתַּ֨רְתִּי פָנַ֥/י רֶ֨גַע֙ מִמֵּ֔/ךְ וּ/בְ/חֶ֥סֶד עוֹלָ֖ם רִֽחַמְתִּ֑י/ךְ אָמַ֥ר גֹּאֲלֵ֖/ךְ יְהוָֽה", "en": {"kjv": "In a little wrath I hid my face from thee for a moment; but with everlasting kindness will I have mercy on thee, saith the Lord thy Redeemer.", "web": "In overflowing wrath I hid my face from you for a moment; but with everlasting loving kindness will I have mercy on you,” says Yahweh your Redeemer.", "bsb": "In a surge of anger I hid My face from you for a moment, but with everlasting kindness I will have compassion on you,” says the LORD your Redeemer.", "asv": "In overflowing wrath I hid my face from thee for a moment; but with everlasting lovingkindness will I have mercy on thee, saith Jehovah thy Redeemer.", "ylt": "In overflowing wrath I hid my face for a moment from thee, And in kindness age-during I have loved thee, Said thy Redeemer--Jehovah!", "dra": "In a moment of indignation have I hid my face a little while from thee, but with everlasting kindness have I had mercy on thee, said the Lord thy Redeemer.", "bbe": "In overflowing wrath my face was veiled from you for a minute, but I will have pity on you for ever, says the Lord who takes up your cause.", "geneva": "For a moment, in mine anger, I hid my face from thee for a litle season, but with euerlasting mercy haue I had compassion on thee, sayth the Lord thy redeemer.", "wycliffe": "In a moment of indignacioun Y hidde my face a litil fro thee, and in merci euerlastynge Y hadde merci on thee, seide thin ayenbiere, the Lord.", "rotherham": "In an overflow of vexation, I hid my face for a moment, from thee, But, with lovingkindness age-abiding, have I had compassion on thee,—saith thy Redeemer Yahweh.", "darby": "In the outpouring of wrath have I hid my face from thee for a moment; but with everlasting loving-kindness will I have mercy on thee, saith Jehovah, thy Redeemer.", "twenty": "", "jps": "In a little wrath I hid My face from thee for a moment; but with everlasting kindness will I have compassion on thee, saith HaShem thy Redeemer.", "acv": "In overflowing wrath I hid my face from thee for a moment, but with everlasting loving kindness I will have mercy on thee, says Jehovah thy Redeemer.", "anderson": "", "haweis": "", "noyes": "In overflowing wrath I hid my face from thee for a moment. But with everlasting kindness will I have mercy upon thee, Saith thy redeemer, Jehovah.", "webster": "In a little wrath I hid my face from thee for a moment; but with everlasting kindness will I have mercy on thee, saith the LORD thy Redeemer.", "vulgate": "in momento indignationis abscondi faciem meam parumper a te et in misericordia sempiterna misertus sum tui dixit redemptor tuus Dominus;", "brenton": "In a little wrath I turned away my face from thee; but with everlasting mercy will I have compassion upon thee, saith the Lord that delivers thee."}}, {"v": 9, "ref": "54:9", "o": "כִּי מֵ֥י נֹ֨חַ֙ זֹ֣את לִ֔/י אֲשֶׁ֣ר נִשְׁבַּ֗עְתִּי מֵ/עֲבֹ֥ר מֵי נֹ֛חַ ע֖וֹד עַל הָ/אָ֑רֶץ כֵּ֥ן נִשְׁבַּ֛עְתִּי מִ/קְּצֹ֥ף עָלַ֖יִ/ךְ וּ/מִ/גְּעָר בָּֽ/ךְ", "en": {"kjv": "For this is as the waters of Noah unto me: for as I have sworn that the waters of Noah should no more go over the earth; so have I sworn that I would not be wroth with thee, nor rebuke thee.", "web": "“For this is like the waters of Noah to me; for as I have sworn that the waters of Noah shall no more go over the earth, so have I sworn that I will not be angry with you, nor rebuke you.", "bsb": "“For to Me this is like the days of Noah, when I swore that the waters of Noah would never again cover the earth. So I have sworn that I will not be angry with you or rebuke you.", "asv": "For this isasthe waters of Noah unto me; for as I have sworn that the waters of Noah shall no more go over the earth, so have I sworn that I will not be wroth with thee, nor rebuke thee.", "ylt": "For, the waters of Noah is this to Me, In that I have sworn--the waters of Noah Do not pass again over the earth--So I have sworn, Wrath is not upon thee, Nor rebuke against thee.", "dra": "This thing is to me as in the days of Noe, to whom I swore, that I would no more bring in the waters of Noe upon the earth: so have I sworn not to be angry with thee, and not to rebuke thee.", "bbe": "For this is like the days of Noah to me: for as I took an oath that the waters of Noah would never again go over the earth, so have I taken an oath that I will not again be angry with you, or say bitter words to you.", "geneva": "For this is vnto me as the waters of Noah: for as I haue sworne that the waters of Noah should no more goe ouer the earth, so haue I sworne that I would not be angrie with thee, nor rebuke thee.", "wycliffe": "As in the daies of Noe, this thing is to me, to whom Y swoor, that Y schulde no more bringe watris of the greet flood on the erthe; so Y swoor, that Y be no more wrooth to thee, and that Y blame not thee.", "rotherham": "For, the waters of Noah, is this unto me,—As to which I sware that the waters of Noah should not again pass over the earth, So have I sworn Not to be vexed with thee Nor to rebuke thee.", "darby": "For this is [as] the waters of Noah unto me, since I have sworn that the waters of Noah should no more go over the earth: so have I sworn that I will no more be wroth with thee, nor rebuke thee.", "twenty": "", "jps": "For this is as the waters of Noah unto Me; for as I have sworn that the waters of Noah should no more go over the earth, so have I sworn that I would not be wroth with thee, nor rebuke thee.", "acv": "For this is as the waters of Noah to me. For as I have sworn that the waters of Noah shall no more go over the earth, so I have sworn that I will not be angry with thee, nor rebuke thee.", "anderson": "", "haweis": "", "noyes": "As in the time of the waters of Noah, so shall it be now; As I swore that the waters of Noah should no more go over the earth, So do I swear that I will not be angry with thee, nor rebuke thee.", "webster": "For this [is as] the waters of Noah to me: for [as] I have sworn that the waters of Noah shall no more overflow the earth; so have I sworn that I will not be wroth with thee, nor rebuke thee.", "vulgate": "sicut in diebus Noe istud mihi est cui iuravi ne inducerem aquas Noe ultra super terram sic iuravi ut non irascar tibi et non increpem te;", "brenton": "From the time of the water of Noe this is my purpose: as I sware to him at that time, saying of the earth, I will no more be wroth with thee, neither when thou art threatened,"}}, {"v": 10, "ref": "54:10", "o": "כִּ֤י הֶֽ/הָרִים֙ יָמ֔וּשׁוּ וְ/הַ/גְּבָע֖וֹת תְּמוּטֶ֑נָה וְ/חַסְדִּ֞/י מֵ/אִתֵּ֣/ךְ לֹֽא יָמ֗וּשׁ וּ/בְרִ֤ית שְׁלוֹמִ/י֙ לֹ֣א תָמ֔וּט אָמַ֥ר מְרַחֲמֵ֖/ךְ יְהוָֽה", "en": {"kjv": "For the mountains shall depart, and the hills be removed; but my kindness shall not depart from thee, neither shall the covenant of my peace be removed, saith the Lord that hath mercy on thee.", "web": "For the mountains may depart, and the hills be removed; but my loving kindness shall not depart from you, neither shall my covenant of peace be removed,” says Yahweh who has mercy on you.", "bsb": "Though the mountains may be removed and the hills may be shaken, My loving devotion will not depart from you, and My covenant of peace will not be broken,” says the LORD, who has compassion on you.", "asv": "For the mountains may depart, and the hills be removed; but my lovingkindness shall not depart from thee, neither shall my covenant of peace be removed, saith Jehovah that hath mercy on thee.", "ylt": "For the mountains depart, and the hills remove, And My kindness from thee departeth not, And the covenant of My peace removeth not, Said hath thy loving one--Jehovah.", "dra": "For the mountains shall be moved, and the hills shall tremble; but my mercy shall not depart from thee, and the covenant of my peace shall not be moved: said the Lord that hath mercy on thee.", "bbe": "For the mountains may be taken away, and the hills be moved out of their places, but my love will not be taken from you, or my agreement of peace broken, says the Lord, who has had mercy on you.", "geneva": "For the mountaines shall remoue and the hilles shall fall downe: but my mercy shall not depart from thee, neither shall the couenant of my peace fall away, saith the Lord, that hath compassion on thee.", "wycliffe": "Forsothe hillis schulen be mouyd togidere, and litle hillis schulen tremble togidere; but my merci schal not go a wei fro thee, and the boond of my pees schal not be mouyd, seide the merciful doere, the Lord.", "rotherham": "For, the mountains, may move away, And the hills, may be shaken,—But, my lovingkindness, from thee, shall not move away, And, my covenant of peace, shall not be shaken, saith he who hath compassion upon thee—Yahweh.", "darby": "For the mountains shall depart, and the hills be removed; but my loving-kindness shall not depart from thee, neither shall my covenant of peace be removed, saith Jehovah, that hath mercy on thee.", "twenty": "", "jps": "For the mountains may depart, and the hills be removed; but My kindness shall not depart from thee, neither shall My covenant of peace be removed, saith HaShem that hath compassion on thee.", "acv": "For the mountains may depart, and the hills be removed, but my loving kindness shall not depart from thee, nor shall my covenant of peace be removed, says Jehovah who has mercy on thee.", "anderson": "", "haweis": "", "noyes": "For the mountains shall depart, And the hills be overthrown, But my kindness shall not depart from thee, Nor shall my covenant of peace be overthrown, Saith Jehovah, that hath pity on thee.", "webster": "For the mountains shall depart, and the hills be removed, but my kindness shall not depart from thee, neither shall the covenant of my peace be removed, saith the LORD that hath mercy on thee.", "vulgate": "montes enim commovebuntur et colles contremescent misericordia autem mea non recedet et foedus pacis meae non movebitur dixit miserator tuus Dominus;", "brenton": "shall the mountains depart, nor shall thy hills be removed: so neither shall my mercy fail thee, nor shall the covenant of thy peace be at all removed: for the Lord who is gracious to thee has spoken it."}}, {"v": 11, "ref": "54:11", "o": "עֲנִיָּ֥ה סֹעֲרָ֖ה לֹ֣א נֻחָ֑מָה הִנֵּ֨ה אָנֹכִ֜י מַרְבִּ֤יץ בַּ/פּוּךְ֙ אֲבָנַ֔יִ/ךְ וִ/יסַדְתִּ֖י/ךְ בַּ/סַּפִּירִֽים", "en": {"kjv": "O thou afflicted, tossed with tempest, and not comforted, behold, I will lay thy stones with fair colours, and lay thy foundations with sapphires.", "web": "“You afflicted, tossed with storms, and not comforted, behold, I will set your stones in beautiful colors, and lay your foundations with sapphires.", "bsb": "“O afflicted city, lashed by storms, without solace, surely I will set your stones in antimony and lay your foundations with sapphires.", "asv": "O thou afflicted, tossed with tempest, and not comforted, behold, I will set thy stones in fair colors, and lay thy foundations with sapphires.", "ylt": "O afflicted, storm-tossed, not comforted, Lo, I am laying with cement thy stones, And have founded thee with sapphires,", "dra": "O poor little one, tossed with tempest, without all comfort, behold I will lay thy stones in order, and will lay thy foundations with sapphires,", "bbe": "O troubled one, storm-crushed, uncomforted! see, your stones will be framed in fair colours, and your bases will be sapphires.", "geneva": "O thou afflicted and tossed with tempest, that hast no comfort, beholde, I wil lay thy stones with the carbuncle, and lay thy foundation with saphirs,", "wycliffe": "Thou litle and pore, drawun out bi tempest, with outen ony coumfort, lo! Y schal strewe thi stoonys bi ordre, and Y schal founde thee in safiris;", "rotherham": "O thou humbled one storm-tossed, uncomforted,—Lo! I, am about to set in antimony, thy stones, And will found thee in sapphires;", "darby": "[Thou] afflicted, tossed with tempest, not comforted! Behold, I will set thy stones in antimony, and lay thy foundations with sapphires;", "twenty": "", "jps": "O thou afflicted, tossed with tempest, and not comforted, behold, I will set thy stones in fair colours, and lay thy foundations with sapphires.", "acv": "O thou afflicted, tossed with tempest, and not comforted, behold, I will set thy stones in fair colors, and lay thy foundations with sapphires.", "anderson": "", "haweis": "", "noyes": "O thou afflicted, beaten with the storm, destitute of consolation! Behold, I lay thy stones in cement of vermilion, And thy foundations with sapphires.", "webster": "Oh thou afflicted, tossed with tempest, [and] not comforted, behold, I will lay thy stones with fair colors, and lay thy foundations with sapphires.", "vulgate": "paupercula tempestate convulsa absque ulla consolatione ecce ego sternam per ordinem lapides tuos et fundabo te in sapphyris;", "brenton": "Afflicted and outcast thou has not been comforted: behold, I will prepare carbuncle for thy stones, and sapphire for thy foundations;"}}, {"v": 12, "ref": "54:12", "o": "וְ/שַׂמְתִּ֤י כַּֽדְכֹד֙ שִׁמְשֹׁתַ֔יִ/ךְ וּ/שְׁעָרַ֖יִ/ךְ לְ/אַבְנֵ֣י אֶקְדָּ֑ח וְ/כָל גְּבוּלֵ֖/ךְ לְ/אַבְנֵי חֵֽפֶץ", "en": {"kjv": "And I will make thy windows of agates, and thy gates of carbuncles, and all thy borders of pleasant stones.", "web": "I will make your pinnacles of rubies, and your gates of sparkling jewels, and all your walls of precious stones.", "bsb": "I will make your pinnacles of rubies, your gates of sparkling jewels, and all your walls of precious stones.", "asv": "And I will make thy pinnacles of rubies, and thy gates of carbuncles, and all thy border of precious stones.", "ylt": "And have made of agate thy pinnacles, And thy gates of carbuncle stones, And all thy border of stones of delight,", "dra": "And I will make thy bulwarks of jasper: and thy gates of graven stones, and all thy borders of desirable stones.", "bbe": "I will make your towers of rubies, and your doors of carbuncles, and the wall round you will be of all sorts of beautiful stones.", "geneva": "And I will make thy windowes of emeraudes, and thy gates shining stones, and all thy borders of pleasant stones.", "wycliffe": "and Y schal sette iaspis thi touris, and thi yatis in to grauun stoonys, and alle thin eendis in to desirable stoonys.", "rotherham": "And make rubies, thy battlements, And thy gates, sparkling stones,—And, all thy boundaries, stones of delight;", "darby": "and I will make thy battlements of rubies, and thy gates of carbuncles, and all thy borders of precious stones.", "twenty": "", "jps": "And I will make thy pinnacles of rubies, and thy gates of carbuncles, and all thy border of precious stones.", "acv": "And I will make thy pinnacles of rubies, and thy gates of carbuncles, and all thy border of precious stones.", "anderson": "", "haweis": "", "noyes": "And I will make thy battlements of rubies, And thy gates of carbuncles, And all thy borders fill of precious stones.", "webster": "And I will make thy windows of agates, and thy gates of carbuncles, and all thy borders of pleasant stones.", "vulgate": "et ponam iaspidem propugnacula tua et portas tuas in lapides sculptos et omnes terminos tuos in lapides desiderabiles;", "brenton": "and I will make thy buttresses jasper, and thy gates crystal, and thy border precious stones."}}, {"v": 13, "ref": "54:13", "o": "וְ/כָל בָּנַ֖יִ/ךְ לִמּוּדֵ֣י יְהוָ֑ה וְ/רַ֖ב שְׁל֥וֹם בָּנָֽיִ/ךְ", "en": {"kjv": "And all thy children shall be taught of the Lord; and great shall be the peace of thy children.", "web": "All your children shall be taught of Yahweh; and great shall be the peace of your children.", "bsb": "Then all your sons will be taught by the LORD, and great will be their prosperity.", "asv": "And all thy children shall be taught of Jehovah; and great shall be the peace of thy children.", "ylt": "And all thy sons are taught of Jehovah, And abundant is the peace of thy sons.", "dra": "All thy children shall be taught of the Lord: and great shall be the peace of thy children.", "bbe": "And all your builders will be made wise by the Lord; and great will be the peace of your children.", "geneva": "And all thy children shalbe taught of the Lord, and much peace shalbe to thy children.", "wycliffe": "`Y schal make alle thi sones tauyt of the Lord; and the multitude of pees to thi sones,", "rotherham": "And, all thy children, shall be the instructed of Yahweh,—And, great, shall be the prosperity of thy children.", "darby": "And all thy children [shall be] taught of Jehovah, and great shall be the peace of thy children.", "twenty": "", "jps": "And all thy children shall be taught of HaShem; and great shall be the peace of thy children.", "acv": "And all thy sons shall be taught of Jehovah, and great shall be the peace of thy sons.", "anderson": "", "haweis": "", "noyes": "All thy children shall be taught by Jehovah, And great shall be the prosperity of thy children.", "webster": "And all thy children [shall be] taught from the LORD; and great [shall be] the peace of thy children.", "vulgate": "universos filios tuos doctos a Domino et multitudinem pacis filiis tuis;", "brenton": "And I will cause all thy sons to be taught of God, and thy children to be in great peace."}}, {"v": 14, "ref": "54:14", "o": "בִּ/צְדָקָ֖ה תִּכּוֹנָ֑נִי רַחֲקִ֤י מֵ/עֹ֨שֶׁק֙ כִּֽי לֹ֣א תִירָ֔אִי וּ/מִ֨/מְּחִתָּ֔ה כִּ֥י לֹֽא תִקְרַ֖ב אֵלָֽיִ/ךְ", "en": {"kjv": "In righteousness shalt thou be established: thou shalt be far from oppression; for thou shalt not fear: and from terror; for it shall not come near thee.", "web": "In righteousness you shall be established: you shall be far from oppression, for you shall not be afraid; and from terror, for it shall not come near you.", "bsb": "In righteousness you will be established, far from oppression, for you will have no fear. Terror will be far removed, for it will not come near you.", "asv": "In righteousness shalt thou be established: thou shalt be far from oppression, for thou shalt not fear; and from terror, for it shall not come near thee.", "ylt": "In righteousness thou establishest thyself, Be far from oppression, for thou fearest not, And from ruin, for it cometh not near unto thee.", "dra": "And thou shalt be founded in justice: depart far from oppression, for thou shalt not fear; and from terror, for it shall not come near thee.", "bbe": "All your rights will be made certain to you: have no fear of evil, and destruction will not come near you.", "geneva": "In righteousnes shalt thou be established, and be farre from oppression: for thou shalt not feare it: and from feare, for it shall not come neere thee.", "wycliffe": "and thou schalt be foundid in riytfulnesse. Go thou awei fer fro fals caleng, for thou schalt not drede; and fro drede, for it schal not neiye to thee.", "rotherham": "In righteousness, shalt thou be established,—Be thou far from oppression—But indeed thou shalt not fear, And from crushing calamity—But indeed it shall not come nigh unto thee.", "darby": "In righteousness shalt thou be established: thou shalt be far from oppression, for thou shalt not fear; and from terror, for it shall not come near thee.", "twenty": "", "jps": "In righteousness shalt thou be established; be thou far from oppression, for thou shalt not fear, and from ruin, for it shall not come near thee.", "acv": "Thou shall be established in righteousness. Thou shall be far from oppression, for thou shall not fear, and from terror, for it shall not come near thee.", "anderson": "", "haweis": "", "noyes": "By righteousness shalt thou be established; Be thou far from anxiety, for thou shalt have nothing to fear, And from terror, for it shall not come near thee.", "webster": "In righteousness shalt thou be established: thou shalt be far from oppression; for thou shalt not fear: and from terror; for it shall not come near thee.", "vulgate": "et in iustitia fundaberis recede procul a calumnia quia non timebis et a pavore quia non adpropinquabit tibi;", "brenton": "And thou shalt be built in righteousness: abstain from injustice, and thou shalt not fear; and trembling shall not come nigh thee."}}, {"v": 15, "ref": "54:15", "o": "הֵ֣ן גּ֥וֹר יָג֛וּר אֶ֖פֶס מֵֽ/אוֹתִ֑/י מִי גָ֥ר אִתָּ֖/ךְ עָלַ֥יִ/ךְ יִפּֽוֹל", "en": {"kjv": "Behold, they shall surely gather together, but not by me: whosoever shall gather together against thee shall fall for thy sake.", "web": "Behold, they may gather together, but not by me: whoever shall gather together against you shall fall because of you.", "bsb": "If anyone attacks you, it is not from Me; whoever assails you will fall before you.", "asv": "Behold, they may gather together, but not by me: whosoever shall gather together against thee shall fall because of thee.", "ylt": "Lo, he doth diligently assemble without My desire, Who hath assembled near thee? By thee he falleth!", "dra": "Behold, an inhabitant shall come, who was not with me, he that was a stranger to thee before, shall be joined to thee.", "bbe": "See, they may be moved to war, but not by my authority: all those who come together to make an attack on you, will be broken against you.", "geneva": "Beholde, the enemie shall gather himselfe, but without me: whosoeuer shall gather himselfe in thee, against thee, shall fall.", "wycliffe": "Lo! a straunger schal come, that was not with me; he, that was sum tyme thi comelyng, schal be ioyned to thee.", "rotherham": "Lo! they would, quarrel, with thee—not at all from me,—Whoso hath quarrelled with thee, over thee, shall fall.", "darby": "Behold, they shall surely gather together, [but] not by me: whosoever gathereth together against thee shall fall because of thee.", "twenty": "", "jps": "Behold, they may gather together, but not by Me; whosoever shall gather together against thee shall fall because of thee.", "acv": "Behold, they may gather together, but not by me. Whoever shall gather together against thee shall fall because of thee.", "anderson": "", "haweis": "", "noyes": "If any be leagued against thee, it is not by my command; Whoever shall be leagued against thee shall come over to thee.", "webster": "Behold, they shall surely assemble [but] not by me: whoever shall assemble against thee shall fall for thy sake.", "vulgate": "ecce accola veniet qui non erat mecum advena quondam tuus adiungetur tibi;", "brenton": "Behold, strangers shall come to thee by me, and shall sojourn with thee, and shall run to thee for refuge."}}, {"v": 16, "ref": "54:16", "o": "הן הִנֵּ֤ה אָֽנֹכִי֙ בָּרָ֣אתִי חָרָ֔שׁ נֹפֵ֨חַ֙ בְּ/אֵ֣שׁ פֶּחָ֔ם וּ/מוֹצִ֥יא כְלִ֖י לְ/מַעֲשֵׂ֑/הוּ וְ/אָנֹכִ֛י בָּרָ֥אתִי מַשְׁחִ֖ית לְ/חַבֵּֽל", "en": {"kjv": "Behold, I have created the smith that bloweth the coals in the fire, and that bringeth forth an instrument for his work; and I have created the waster to destroy.", "web": "“Behold, I have created the smith who blows the fire of coals, and brings out a weapon for his work; and I have created the waster to destroy.", "bsb": "Behold, I have created the craftsman who fans the coals into flame and forges a weapon fit for its task; and I have created the destroyer to wreak havoc.", "asv": "Behold, I have created the smith that bloweth the fire of coals, and bringeth forth a weapon for his work; and I have created the waster to destroy.", "ylt": "Lo, I--I have prepared an artisan, Blowing on a fire of coals, And bringing out an instrument for his work, And I have prepared a destroyer to destroy.", "dra": "Behold, I have created the smith that bloweth the coals in the fire, and bringeth forth an instrument for his work, and I have created the killer to destroy.", "bbe": "See, I have made the iron-worker, blowing on the burning coals, and making the instrument of war by his work; and I have made the waster for destruction.", "geneva": "Beholde, I haue created the smith that bloweth the coales in the fire, and him that bringeth forth an instrument for his worke, and I haue created the destroyer to destroy.", "wycliffe": "Lo! Y made a smyth blowynge coolis in fier, and bringynge forth a vessel in to his werk; and Y haue maad a sleere, for to leese.", "rotherham": "Lo! I, have created the smith, who bloweth up a fire of coals, And who bringeth forth an instrument for his work,—And, I, have created the waster to destroy:", "darby": "Behold, it is I who have created the smith that bloweth in the fire of coal, and that bringeth forth an instrument for his work; and I have created the destroyer to ravage.", "twenty": "", "jps": "Behold, I have created the smith that bloweth the fire of coals, and bringeth forth a weapon for his work; and I have created the waster to destroy.", "acv": "Behold, I have created the smith who blows the fire of coals, and brings forth a weapon for his work. And I have created the waster to destroy.", "anderson": "", "haweis": "", "noyes": "Behold, I create the smith, Who bloweth up the coals into a fire, And produceth an instrument for his work; I also create the destroyer to lay waste.", "webster": "Behold, I have created the smith that bloweth the coals in the fire, and that bringeth forth an instrument for his work; and I have created the waster to destroy.", "vulgate": "ecce ego creavi fabrum sufflantem in igne prunas et proferentem vas in opus suum et ego creavi interfectorem ad disperdendum;", "brenton": "Behold, I have created thee, not as the coppersmith blowing coals, and bringing out a vessel fit for work; but I have created thee, not for ruin, that I should destroy thee."}}, {"v": 17, "ref": "54:17", "o": "כָּל כְּלִ֞י יוּצַ֤ר עָלַ֨יִ/ךְ֙ לֹ֣א יִצְלָ֔ח וְ/כָל לָשׁ֛וֹן תָּֽקוּם אִתָּ֥/ךְ לַ/מִּשְׁפָּ֖ט תַּרְשִׁ֑יעִי זֹ֡את נַחֲלַת֩ עַבְדֵ֨י יְהוָ֧ה וְ/צִדְקָתָ֛/ם מֵ/אִתִּ֖/י נְאֻם יְהוָֽה", "en": {"kjv": "No weapon that is formed against thee shall prosper; and every tongue that shall rise against thee in judgment thou shalt condemn. This is the heritage of the servants of the Lord, and their righteousness is of me, saith the Lord.", "web": "No weapon that is formed against you will prevail; and you will condemn every tongue that rises against you in judgment. This is the heritage of the servants of Yahweh, and their righteousness which is of me,” says Yahweh.", "bsb": "No weapon formed against you shall prosper, and you will refute every tongue that accuses you. This is the heritage of the servants of the LORD, and their vindication is from Me,” declares the LORD.", "asv": "No weapon that is formed against thee shall prosper; and every tongue that shall rise against thee in judgment thou shalt condemn. This is the heritage of the servants of Jehovah, and their righteousness which is of me, saith Jehovah.", "ylt": "No weapon formed against thee prospereth, And every tongue rising against thee, In judgment thou condemnest. This is the inheritance of the servants of Jehovah, And their righteousness from me, an affirmation of Jehovah!", "dra": "No weapon that is formed against thee shall prosper: and every tongue that resisteth thee in judgment, thou shalt condemn. This is the inheritance of the servants of the Lord, and their justice with me, saith the Lord.", "bbe": "No instrument of war which is formed against you will be of any use; and every tongue which says evil against you will be judged false. This is the heritage of the servants of the Lord, and their righteousness comes from me, says the Lord.", "geneva": "But all the weapons that are made against thee, shall not prosper: and euery tongue that shall rise against thee in iudgement, thou shalt condemne. This is the heritage of the Lords seruants, and their righteousnesse is of me, sayth the Lord.", "wycliffe": "Ech vessel which is maad ayens thee, schal not be dressid; and in the doom thou schalt deme ech tunge ayenstondynge thee. This is the eritage of the seruauntis of the Lord, and the riytfulnesse of hem at me, seith the Lord.", "rotherham": "No instrument formed against thee, shall prosper, And every tongue that riseth against thee in judgment, shalt thou prove to be lawless,—This is the inheritance of the servants of Yahweh. And, their righteousness, is from me, Declareth Yahweh.", "darby": "No weapon that is prepared against thee shall prosper; and every tongue that riseth against thee in judgment, thou shalt condemn. This is the inheritance of the servants of Jehovah; and their righteousness is of me, saith Jehovah.", "twenty": "", "jps": "No weapon that is formed against thee shall prosper; and every tongue that shall rise against thee in judgment thou shalt condemn. This is the heritage of the servants of HaShem, and their due reward from Me, saith HaShem.", "acv": "No weapon that is formed against thee shall prosper. And every tongue that shall rise against thee in judgment thou shall condemn. This is the heritage of the servants of Jehovah, and their righteousness which is of me, says Jehovah.", "anderson": "", "haweis": "", "noyes": "Whatever weapon is formed against thee, it shall not prosper; And against every tongue that contendeth with thee, thou shalt obtain thy cause. This is the inheritance of the servants of Jehovah, And the blessing which they receive from me, saith Jehovah.", "webster": "No weapon that is formed against thee shall prosper; and every tongue [that] shall rise against thee in judgment thou shalt condemn. This [is] the heritage of the servants of the LORD, and their righteousness [is] from me, saith the LORD.", "vulgate": "omne vas quod fictum est contra te non dirigetur et omnem linguam resistentem tibi in iudicio iudicabis haec hereditas servorum Domini et iustitia eorum apud me dicit Dominus;", "brenton": "I will not suffer any weapon formed against thee to prosper; and every voice that shall rise up against thee for judgment, thou shalt vanquish them all; and thine adversaries shall be condemned thereby. There is an inheritance to them that serve the Lord, and ye shall be righteous before me, saith the Lord."}}]}, {"c": 55, "verses": [{"v": 1, "ref": "55:1", "o": "ה֤וֹי כָּל צָמֵא֙ לְכ֣וּ לַ/מַּ֔יִם וַ/אֲשֶׁ֥ר אֵֽין ל֖/וֹ כָּ֑סֶף לְכ֤וּ שִׁבְרוּ֙ וֶֽ/אֱכֹ֔לוּ וּ/לְכ֣וּ שִׁבְר֗וּ בְּ/לוֹא כֶ֛סֶף וּ/בְ/ל֥וֹא מְחִ֖יר יַ֥יִן וְ/חָלָֽב", "en": {"kjv": "Ho, every one that thirsteth, come ye to the waters, and he that hath no money; come ye, buy, and eat; yea, come, buy wine and milk without money and without price.", "web": "“Come, everyone who thirsts, to the waters! Come, he who has no money, buy, and eat! Yes, come, buy wine and milk without money and without price.", "bsb": "“Come, all you who are thirsty, come to the waters; and you without money, come, buy, and eat! Come, buy wine and milk without money and without cost!", "asv": "Ho, every one that thirsteth, come ye to the waters, and he that hath no money; come ye, buy, and eat; yea, come, buy wine and milk without money and without price.", "ylt": "Ho, every thirsty one, come ye to the waters, And he who hath no money, Come ye, buy and eat, yea, come, buy Without money and without price, wine and milk.", "dra": "All you that thirst, come to the waters: and you that have no money make haste, buy, and eat: come ye, buy wine and milk without money, and without any price.", "bbe": "Ho! everyone in need, come to the waters, and he who has no strength, let him get food: come, get bread without money; wine and milk without price.", "geneva": "Ho, euery one that thirsteth, come ye to the waters, and ye that haue no siluer, come, bye and eate: come, I say, bye wine and milke without siluer and without money.", "wycliffe": "Alle that thirsten, come ye to watris, and ye han not siluer, haaste, bie ye, and ete ye; come ye, bie ye, with out siluer and with outen ony chaungyng, wyn and mylk.", "rotherham": "Ho! every one that thirsteth! Come ye to the waters, Yea he that hath no money,—Come ye—buy corn, and eat, Yea come—buy corn without money, And without price, wine and milk,", "darby": "Ho, every one that thirsteth, come ye to the waters; and he that hath no money, come ye, buy, and eat: yea, come, buy wine and milk without money and without price!", "twenty": "", "jps": "Ho, every one that thirsteth, come ye for water, and he that hath no money; come ye, buy, and eat; yea, come, buy wine and milk without money and without price.", "acv": "Ho, everyone who thirsts, come ye to the waters. And he who has no money, come ye, buy, and eat. Yea, come, buy wine and milk without money and without price.", "anderson": "", "haweis": "", "noyes": "Ho, every one that thirsteth, come ye to the waters! Even ye that have no money, come ye, buy and eat! Yea, come, buy wine and milk, Without money and without price.", "webster": "Ho, every one that thirsteth, come ye to the waters, and he that hath no money; come ye, buy, and eat; yes, come, buy wine and milk without money and without price.", "vulgate": "o omnes sitientes venite ad aquas et qui non habetis argentum properate emite et comedite venite emite absque argento et absque ulla commutatione vinum et lac;", "brenton": "Ye that thirst, go to the water, and all that have no money, go and buy; and eat and drink wine and fat without money or price."}}, {"v": 2, "ref": "55:2", "o": "לָ֤/מָּה תִשְׁקְלוּ כֶ֨סֶף֙ בְּֽ/לוֹא לֶ֔חֶם וִ/יגִיעֲ/כֶ֖ם בְּ/ל֣וֹא לְ/שָׂבְעָ֑ה שִׁמְע֨וּ שָׁמ֤וֹעַ אֵלַ/י֙ וְ/אִכְלוּ ט֔וֹב וְ/תִתְעַנַּ֥ג בַּ/דֶּ֖שֶׁן נַפְשְׁ/כֶֽם", "en": {"kjv": "Wherefore do ye spend money for that which is not bread? and your labour for that which satisfieth not? hearken diligently unto me, and eat ye that which is good, and let your soul delight itself in fatness.", "web": "Why do you spend money for that which is not bread? and your labor for that which doesn’t satisfy? listen diligently to me, and eat you that which is good, and let your soul delight itself in fatness.", "bsb": "Why spend money on that which is not bread, and your labor on that which does not satisfy? Listen carefully to Me, and eat what is good, and your soul will delight in the richest of foods.", "asv": "Wherefore do ye spend money for that which is not bread? and your labor for that which satisfieth not? hearken diligently unto me, and eat ye that which is good, and let your soul delight itself in fatness.", "ylt": "Why do ye weigh money for that which is not bread? And your labour for that which is not for satiety? Hearken diligently unto me, and eat good, And your soul doth delight itself in fatness.", "dra": "Why do you spend money for that which is not bread, and your labour for that which doth not satisfy you? Hearken diligently to me, and eat that which is good, and your soul shall be delighted in fatness.", "bbe": "Why do you give your money for what is not bread, and the fruit of your work for what will not give you pleasure? Give ear to me, so that your food may be good, and you may have the best in full measure.", "geneva": "Wherefore doe ye lay out siluer and not for bread? and your labour without being satisfied? hearken diligently vnto me, and eate that which is good, and let your soule delite in fatnes.", "wycliffe": "Whi peisen ye siluer, and not in looues, and youre trauel, not in fulnesse? Ye herynge here me, and ete ye good, and youre soule schal delite in fatnesse.", "rotherham": "Wherefore should ye spend, Money, for that which is not bread? Or your labour, for that which, satisfieth not? Keep on hearkening unto me, And, so eat that which is good, And let your soul take exquisite delight in fatness:", "darby": "Wherefore do ye spend money for [that which is] not bread? and your labour for that which satisfieth not? Hearken diligently unto me, and eat ye [that which is] good, and let your soul delight itself in fatness.", "twenty": "", "jps": "Wherefore do ye spend money for that which is not bread? and your gain for that which satisfieth not? Hearken diligently unto Me, and eat ye that which is good, and let your soul delight itself in fatness.", "acv": "Why do ye spend money for that which is not bread, and your labor for that which does not satisfy? Hearken diligently to me, and eat ye that which is good, and let your soul delight itself in fatness.", "anderson": "", "haweis": "", "noyes": "Wherefore do ye spend your money for that which is not bread, And your substance for that which doth not satisfy? Listen attentively to me; so shall ye eat that which is good, And your soul shall delight itself with delicacies.", "webster": "Why do ye spend money for [that which is] not bread? and your labor for [that which] satisfieth not? hearken diligently to me, and eat ye [that which is] good, and let your soul delight itself in fatness.", "vulgate": "quare adpenditis argentum non in panibus et laborem vestrum non in saturitate audite audientes me et comedite bonum et delectabitur in crassitudine anima vestra;", "brenton": "Wherefore do ye value at the price of money, and give your labour for that which will not satisfy? hearken to me, and ye shall eat that which is good, and your soul shall feast itself on good things."}}, {"v": 3, "ref": "55:3", "o": "הַטּ֤וּ אָזְנְ/כֶם֙ וּ/לְכ֣וּ אֵלַ֔/י שִׁמְע֖וּ וּ/תְחִ֣י נַפְשְׁ/כֶ֑ם וְ/אֶכְרְתָ֤ה לָ/כֶם֙ בְּרִ֣ית עוֹלָ֔ם חַֽסְדֵ֥י דָוִ֖ד הַ/נֶּאֱמָנִֽים", "en": {"kjv": "Incline your ear, and come unto me: hear, and your soul shall live; and I will make an everlasting covenant with you, even the sure mercies of David.", "web": "Turn your ear, and come to me; hear, and your soul shall live: and I will make an everlasting covenant with you, even the sure mercies of David.", "bsb": "Incline your ear and come to Me; listen, so that your soul may live. I will make with you an everlasting covenant— My loving devotion promised to David.", "asv": "Incline your ear, and come unto me; hear, and your soul shall live: and I will make an everlasting covenant with you, even the sure mercies of David.", "ylt": "Incline your ear, and come unto me, Hear, and your soul doth live, And I make for you a covenant age-during, The kind acts of David--that are stedfast.", "dra": "Incline your ear and come to me: hear and your soul shall live, and I will make an everlasting covenant with you, the faithful mercies of David.", "bbe": "Give ear, and come to me, take note with care, so that your souls may have life: and I will make an eternal agreement with you, even the certain mercies of David.", "geneva": "Encline your eares, and come vnto me: heare, and your soule shall liue, and I will make an euerlasting couenant with you, euen the sure mercies of Dauid.", "wycliffe": "Bowe ye youre eere, and `come ye to me; here ye, and youre soule schal lyue; and Y schal smyte with you a couenaunt euerlastynge, the feithful mercies of Dauid.", "rotherham": "Incline your ear, and come unto me, Hearken, That your soul, may live,—That I may solemnise for you a covenant age-abiding, The Lovingkindness to David, well-assured.", "darby": "Incline your ear, and come unto me; hear, and your soul shall live; and I will make an everlasting covenant with you, the sure mercies of David.", "twenty": "", "jps": "Incline your ear, and come unto Me; hear, and your soul shall live; and I will make an everlasting covenant with you, even the sure mercies of David.", "acv": "Incline your ear, and come to me. Hear, and your soul shall live. And I will make an everlasting covenant with you, even the faithful holy things of David.", "anderson": "", "haweis": "", "noyes": "Incline your ear, and come to me; Hear, and your soul shall live! And I will make with you an everlasting covenant; I will give you the sure mercies of David.", "webster": "Incline your ear, and come to me: hear, and your soul shall live; and I will make an everlasting covenant with you, [even] the sure mercies of David.", "vulgate": "inclinate aurem vestram et venite ad me audite et vivet anima vestra et feriam vobis pactum sempiternum misericordias David fideles;", "brenton": "Give heed with your ears, and follow my ways: hearken to me, and your soul shall live in prosperity; and I will make with you an everlasting covenant, the sure mercies of David."}}, {"v": 4, "ref": "55:4", "o": "הֵ֛ן עֵ֥ד לְאוּמִּ֖ים נְתַתִּ֑י/ו נָגִ֥יד וּ/מְצַוֵּ֖ה לְאֻמִּֽים", "en": {"kjv": "Behold, I have given him for a witness to the people, a leader and commander to the people.", "web": "Behold, I have given him for a witness to the peoples, a leader and commander to the peoples.", "bsb": "Behold, I have made him a witness to the nations, a leader and commander of the peoples.", "asv": "Behold, I have given him for a witness to the peoples, a leader and commander to the peoples.", "ylt": "Lo, a witness to peoples I have given him, A leader and commander to peoples.", "dra": "Behold I have given him for a witness to the people, for a leader and a master to the Gentiles.", "bbe": "See, I have given him as a witness to the peoples, a ruler and a guide to the nations.", "geneva": "Beholde, I gaue him for a witnes to the people, for a prince and a master vnto the people.", "wycliffe": "Lo! Y yaf hym a witnesse to puplis, a duyk and a comaundour to folkis.", "rotherham": "Lo! As a witness to the peoples, have I given him,—As a leader and commander to the peoples:", "darby": "Behold, I have given him [for] a witness to the peoples, a prince and commander to the peoples.", "twenty": "", "jps": "Behold, I have given him for a witness to the peoples, a prince and commander to the peoples.", "acv": "Behold, I have given him for a witness to the peoples, a leader and commander to the peoples.", "anderson": "", "haweis": "", "noyes": "Behold, I gave him for a commander to the nations; For a prince, and a lawgiver to the nations.", "webster": "Behold, I have given him [for] a witness to the people, a leader and commander to the people.", "vulgate": "ecce testem populis dedi eum ducem ac praeceptorem gentibus;", "brenton": "Behold I have made him a testimony among the Gentiles, a prince and commander to the Gentiles."}}, {"v": 5, "ref": "55:5", "o": "הֵ֣ן גּ֤וֹי לֹֽא תֵדַע֙ תִּקְרָ֔א וְ/ג֥וֹי לֹֽא יְדָע֖וּ/ךָ אֵלֶ֣י/ךָ יָר֑וּצוּ לְמַ֨עַן֙ יְהוָ֣ה אֱלֹהֶ֔י/ךָ וְ/לִ/קְד֥וֹשׁ יִשְׂרָאֵ֖ל כִּ֥י פֵאֲרָֽ/ךְ", "en": {"kjv": "Behold, thou shalt call a nation that thou knowest not, and nations that knew not thee shall run unto thee because of the Lord thy God, and for the Holy One of Israel; for he hath glorified thee.", "web": "Behold, you shall call a nation that you don’t know; and a nation that didn’t know you shall run to you, because of Yahweh your God, and for the Holy One of Israel; for he has glorified you.”", "bsb": "Surely you will summon a nation you do not know, and nations who do not know you will run to you. For the LORD your God, the Holy One of Israel, has bestowed glory on you.”", "asv": "Behold, thou shalt call a nation that thou knowest not; and a nation that knew not thee shall run unto thee, because of Jehovah thy God, and for the Holy One of Israel; for he hath glorified thee.", "ylt": "Lo, a nation thou knowest not, thou callest, And a nation who know thee not unto thee do run, For the sake of Jehovah thy God, And for the Holy One of Israel, Because He hath beautified thee.", "dra": "Behold thou shalt call a nation, which thou knewest not: and the nations that knew not thee shall run to thee, because of the Lord thy God, and for the Holy One of Israel, for he hath glorified thee.", "bbe": "See, you will send for a nation of which you had no knowledge, and those who had no knowledge of you will come running to you, because of the Lord your God, and because of the Holy One of Israel, for he has given you glory.", "geneva": "Beholde, thou shalt call a nation that thou knowest not, and a nation that knew not thee, shall runne vnto thee, because of the Lord thy God, and the holy one of Israel: for hee hath glorified thee.", "wycliffe": "Lo! thou schalt clepe folkis, whiche thou knewist not; and folkis, that knewen not thee, schulen renne to thee; for thi Lord God, and the hooli of Israel, for he glorifiede thee.", "rotherham": "Lo! A nation thou shalt not know, shalt thou call, And, a nation which hath not known thee, unto thee, shall run,—For the sake of Yahweh thy God, And for the Holy One of Israel, because he hath adorned thee.", "darby": "Behold, thou shalt call a nation thou knowest not, and a nation [that] knew not thee shall run unto thee, because of Jehovah thyGod, and the Holy One of Israel; for he hath glorified thee.", "twenty": "", "jps": "Behold, thou shalt call a nation that thou knowest not, and a nation that knew not thee shall run unto thee; because of HaShem thy G-d, and for the Holy One of Israel, for He hath glorified thee.", "acv": "Behold, thou shall call a nation that thou do not know. And a nation that does not know thee shall run to thee because of Jehovah thy God, and for the Holy One of Israel, for he has glorified thee.", "anderson": "", "haweis": "", "noyes": "Behold, the nation which thou knowest not thou shalt call; And the nation which knew not thee shall run to thee, For the sake of Jehovah, thy God, And of the Holy One of Israel, for he hath glorified thee.", "webster": "Behold, thou shalt call a nation [that] thou knowest not, and nations [that] knew not thee shall run to thee because of the LORD thy God, and for the Holy One of Israel, for he hath glorified thee.", "vulgate": "ecce gentem quam nesciebas vocabis et gentes quae non cognoverunt te ad te current propter Dominum Deum tuum et Sanctum Israhel quia glorificavit te;", "brenton": "Nations which know thee not, shall call upon thee, and peoples which are not acquainted with thee, shall flee to thee for refuge, for the sake of the Lord thy God, the Holy One of Israel; for he has glorified thee."}}, {"v": 6, "ref": "55:6", "o": "דִּרְשׁ֥וּ יְהוָ֖ה בְּ/הִמָּצְא֑/וֹ קְרָאֻ֖/הוּ בִּֽ/הְיוֹת֥/וֹ קָרֽוֹב", "en": {"kjv": "Seek ye the Lord while he may be found, call ye upon him while he is near:", "web": "Seek Yahweh while he may be found; call you on him while he is near:", "bsb": "Seek the LORD while He may be found; call on Him while He is near.", "asv": "Seek ye Jehovah while he may be found; call ye upon him while he is near:", "ylt": "Seek ye Jehovah, while He is found, Call ye Him, while He is near,", "dra": "Seek ye the Lord, while he may be found: call upon him, while he is near.", "bbe": "Make search for the Lord while he is there, make prayer to him while he is near:", "geneva": "Seeke ye the Lord while he may be found: call ye vpon him while he is neere.", "wycliffe": "Seke ye the Lord, while he mai be foundun; clepe ye hym to help, while he is niy.", "rotherham": "Seek Yahweh while he may be found,—Call ye upon him while he is near:", "darby": "Seek ye Jehovah while he may be found, call ye upon him while he is near.", "twenty": "", "jps": "Seek ye HaShem while He may be found, call ye upon Him while He is near;", "acv": "Seek ye Jehovah while he may be found. Call ye upon him while he is near.", "anderson": "", "haweis": "", "noyes": "Seek ye Jehovah, while he may be found; Call upon him while he is near;", "webster": "Seek ye the LORD while he may be found, call ye upon him while he is near:", "vulgate": "quaerite Dominum dum inveniri potest invocate eum dum prope est;", "brenton": "Seek ye the Lord, and when ye find him, call upon him; and when he shall draw nigh to you,"}}, {"v": 7, "ref": "55:7", "o": "יַעֲזֹ֤ב רָשָׁע֙ דַּרְכּ֔/וֹ וְ/אִ֥ישׁ אָ֖וֶן מַחְשְׁבֹתָ֑י/ו וְ/יָשֹׁ֤ב אֶל יְהוָה֙ וִֽ/ירַחֲמֵ֔/הוּ וְ/אֶל אֱלֹהֵ֖י/נוּ כִּֽי יַרְבֶּ֥ה לִ/סְלֽוֹחַ", "en": {"kjv": "Let the wicked forsake his way, and the unrighteous man his thoughts: and let him return unto the Lord, and he will have mercy upon him; and to our God, for he will abundantly pardon.", "web": "let the wicked forsake his way, and the unrighteous man his thoughts; and let him return to Yahweh, and he will have mercy on him; and to our God, for he will abundantly pardon.", "bsb": "Let the wicked man forsake his own way and the unrighteous man his own thoughts; let him return to the LORD, that He may have compassion, and to our God, for He will freely pardon.", "asv": "let the wicked forsake his way, and the unrighteous man his thoughts; and let him return unto Jehovah, and he will have mercy upon him; and to our God, for he will abundantly pardon.", "ylt": "Forsake doth the wicked his way, And the man of iniquity his thoughts, And he returneth to Jehovah, and He pitieth him, And unto our God for He multiplieth to pardon.", "dra": "Let the wicked forsake his way, and the unjust man his thoughts, and let him return to the Lord, and he will have mercy on him, and to our God: for he is bountiful to forgive.", "bbe": "Let the sinner give up his way, and the evil-doer his purpose: and let him come back to the Lord, and he will have mercy on him; and to our God, for there is full forgiveness with him.", "geneva": "Let the wicked forsake his wayes, and the vnrighteous his owne imaginations, and returne vnto the Lord, and he wil haue mercy vpon him: and to our God, for hee is very ready to forgiue.", "wycliffe": "An vnfeithful man forsake his weie, and a wickid man forsake hise thouytis; and turne he ayen to the Lord, and he schal haue merci on hym, and to oure God, for he is myche to foryyue.", "rotherham": "Let the lawless forsake his way, And the man of iniquity, his thoughts,—And let him return unto Yahweh That he may have compassion upon him, And unto our God, For he will abundantly pardon.", "darby": "Let the wicked forsake his way, and the unrighteous man his thoughts; and let him return unto Jehovah, and he will have mercy upon him; and to ourGod, for he will abundantly pardon.", "twenty": "", "jps": "Let the wicked forsake his way, and the man of iniquity his thoughts; and let him return unto HaShem, and He will have compassion upon him, and to our G-d, for He will abundantly pardon", "acv": "Let the wicked man forsake his way, and the unrighteous man his thoughts. And let him return to Jehovah, and he will have mercy upon him, and to our God, for he will abundantly pardon.", "anderson": "", "haweis": "", "noyes": "Let the wicked forsake his way, And the unrighteous man his thoughts; Let him return to Jehovah, and he will have mercy upon him, And to our God, for he will abundantly pardon.", "webster": "Let the wicked forsake his way, and the unrighteous man his thoughts: and let him return to the LORD, and he will have mercy upon him; and to our God, for he will abundantly pardon.", "vulgate": "derelinquat impius viam suam et vir iniquus cogitationes suas et revertatur ad Dominum et miserebitur eius et ad Deum nostrum quoniam multus est ad ignoscendum;", "brenton": "let the ungodly leave his ways, and the transgressor his counsels: and let him return to the Lord, and he shall find mercy; for he shall abundantly pardon your sins."}}, {"v": 8, "ref": "55:8", "o": "כִּ֣י לֹ֤א מַחְשְׁבוֹתַ/י֙ מַחְשְׁב֣וֹתֵי/כֶ֔ם וְ/לֹ֥א דַרְכֵי/כֶ֖ם דְּרָכָ֑/י נְאֻ֖ם יְהוָֽה", "en": {"kjv": "For my thoughts are not your thoughts, neither are your ways my ways, saith the Lord.", "web": "“For my thoughts are not your thoughts, neither are your ways my ways,” says Yahweh.", "bsb": "“For My thoughts are not your thoughts, neither are your ways My ways,” declares the LORD.", "asv": "For my thoughts are not your thoughts, neither are your ways my ways, saith Jehovah.", "ylt": "For not My thoughts are your thoughts, Nor your ways My ways, --an affirmation of Jehovah,", "dra": "For my thoughts are not your thoughts: nor your ways my ways, saith the Lord.", "bbe": "For my thoughts are not your thoughts, or your ways my ways, says the Lord.", "geneva": "For my thoughtes are not your thoughts, neither are your wayes my wayes, sayth the Lord.", "wycliffe": "For why my thouytis ben not youre thouytis, and my weies ben not youre weies, seith the Lord.", "rotherham": "For, my thoughts, are not, your thoughts, Nor, your ways, my ways,—Declareth Yahweh.", "darby": "For my thoughts are not your thoughts, neither are your ways my ways, saith Jehovah.", "twenty": "", "jps": "For My thoughts are not your thoughts, neither are your ways My ways, saith HaShem.", "acv": "For my thoughts are not your thoughts, nor are your ways my ways, says Jehovah.", "anderson": "", "haweis": "", "noyes": "For my thoughts are not your thoughts, Neither are your ways my ways, saith Jehovah.", "webster": "For my thoughts [are] not your thoughts, neither [are] your ways my ways, saith the LORD.", "vulgate": "non enim cogitationes meae cogitationes vestrae neque viae vestrae viae meae dicit Dominus;", "brenton": "For my counsels are not as your counsels, nor are my ways as your ways, saith the Lord."}}, {"v": 9, "ref": "55:9", "o": "כִּֽי גָבְה֥וּ שָׁמַ֖יִם מֵ/אָ֑רֶץ כֵּ֣ן גָּבְה֤וּ דְרָכַ/י֙ מִ/דַּרְכֵי/כֶ֔ם וּ/מַחְשְׁבֹתַ֖/י מִ/מַּחְשְׁבֹתֵי/כֶֽם", "en": {"kjv": "For as the heavens are higher than the earth, so are my ways higher than your ways, and my thoughts than your thoughts.", "web": "“For as the heavens are higher than the earth, so are my ways higher than your ways, and my thoughts than your thoughts.", "bsb": "“For as the heavens are higher than the earth, so My ways are higher than your ways and My thoughts than your thoughts.", "asv": "For as the heavens are higher than the earth, so are my ways higher than your ways, and my thoughts than your thoughts.", "ylt": "For high have the heavens been above the earth, So high have been My ways above your ways, And My thoughts above your thoughts.", "dra": "For as the heavens are exalted above the earth, so are my ways exalted above your ways, and my thoughts above your thoughts.", "bbe": "For as the heavens are higher than the earth, so are my ways higher than your ways, and my thoughts than your thoughts.", "geneva": "For as ye heauens are higher then the earth, so are my wayes higher then your wayes, and my thoughtes aboue your thoughts.", "wycliffe": "For as heuenys ben reisid fro erthe, so my weies ben reisid fro youre weies, and my thouytis fro youre thouytis.", "rotherham": "For, higher, are the heavens than the earth,—So, higher, are My ways than your ways, and My thoughts than your thoughts.", "darby": "For [as] the heavens are higher than the earth, so are my ways higher than your ways, and my thoughts than your thoughts.", "twenty": "", "jps": "For as the heavens are higher than the earth, so are My ways higher than your ways, and My thoughts than your thoughts.", "acv": "For as the heavens are higher than the earth, so are my ways higher than your ways, and my thoughts than your thoughts.", "anderson": "", "haweis": "", "noyes": "For as the heavens are higher than the earth, So are my ways higher than your ways, And my thoughts than your thoughts.", "webster": "For [as] the heavens are higher than the earth, so are my ways higher than your ways, and my thoughts than your thoughts.", "vulgate": "quia sicut exaltantur caeli a terra sic exaltatae sunt viae meae a viis vestris et cogitationes meae a cogitationibus vestris;", "brenton": "But as the heaven is distant from the earth, so is my way distant from your ways, and your thoughts from my mind."}}, {"v": 10, "ref": "55:10", "o": "כִּ֡י כַּ/אֲשֶׁ֣ר יֵרֵד֩ הַ/גֶּ֨שֶׁם וְ/הַ/שֶּׁ֜לֶג מִן הַ/שָּׁמַ֗יִם וְ/שָׁ֨מָּ/ה֙ לֹ֣א יָשׁ֔וּב כִּ֚י אִם הִרְוָ֣ה אֶת הָ/אָ֔רֶץ וְ/הוֹלִידָ֖/הּ וְ/הִצְמִיחָ֑/הּ וְ/נָ֤תַן זֶ֨רַע֙ לַ/זֹּרֵ֔עַ וְ/לֶ֖חֶם לָ/אֹכֵֽל", "en": {"kjv": "For as the rain cometh down, and the snow from heaven, and returneth not thither, but watereth the earth, and maketh it bring forth and bud, that it may give seed to the sower, and bread to the eater:", "web": "For as the rain comes down and the snow from the sky, and doesn’t return there, but waters the earth, and makes it grow and bud, and gives seed to the sower and bread to the eater;", "bsb": "For just as rain and snow fall from heaven and do not return without watering the earth, making it bud and sprout, and providing seed to sow and food to eat,", "asv": "For as the rain cometh down and the snow from heaven, and returneth not thither, but watereth the earth, and maketh it bring forth and bud, and giveth seed to the sower and bread to the eater;", "ylt": "For, as come down doth the shower, And the snow from the heavens, And thither returneth not, But hath watered the earth, And hath caused it to yield, and to spring up, And hath given seed to the sower, and bread to the eater,", "dra": "And as the rain and the snow come down from heaven, and return no more thither, but soak the earth, and water it, and make it to spring, and give seed to the sower, and bread to the eater:", "bbe": "For as the rain comes down, and the snow from heaven, and does not go back again, but gives water to the earth, and makes it fertile, giving seed to the planter, and bread for food;", "geneva": "Surely as the raine commeth downe and the snow from heauen, and returneth not thither, but watereth the earth and maketh it to bring forth and bud, that it may giue seede to the sower, and bread vnto him that eateth,", "wycliffe": "And as reyn and snow cometh doun fro heuene, and turneth no more ayen thidur, but it fillith the erthe, and bischedith it, and makith it to buriowne, and yyueth seed to hym that sowith, and breed to hym that etith,", "rotherham": "For, as the rain and the snow descend from the heavens. And thither, do not return, Except they have watered the earth. And caused it to bring forth and bud,—And given seed to the sower, and bread to the eater,", "darby": "For as the rain cometh down, and the snow from heaven, and returneth not thither, but watereth the earth, and maketh it bring forth and bud, that it may give seed to the sower, and bread to the eater:", "twenty": "", "jps": "For as the rain cometh down and the snow from heaven, and returneth not thither, except it water the earth, and make it bring forth and bud, and give seed to the sower and bread to the eater;", "acv": "For as the rain comes down and the snow from heaven, and returns not there, but waters the earth, and makes it bring forth and bud, and gives seed to the sower and bread to the eater,", "anderson": "", "haweis": "", "noyes": "For as the rain and the snow descend from heaven, And return not thither, But water the earth, and make it bear and put forth its increase, That it may give seed to the sower, and bread to the eater;", "webster": "For as the rain cometh down, and the snow from heaven, and returneth not thither, but watereth the earth, and maketh it bring forth and bud, that it may give seed to the sower, and bread to the eater:", "vulgate": "et quomodo descendit imber et nix de caelo et illuc ultra non revertitur sed inebriat terram et infundit eam et germinare eam facit et dat semen serenti et panem comedenti;", "brenton": "For as rain shall come down, or snow, from heaven, and shall not return until it have saturated the earth, and it bring forth, and bud, and give seed to the sower, and bread for food:"}}, {"v": 11, "ref": "55:11", "o": "כֵּ֣ן יִֽהְיֶ֤ה דְבָרִ/י֙ אֲשֶׁ֣ר יֵצֵ֣א מִ/פִּ֔/י לֹֽא יָשׁ֥וּב אֵלַ֖/י רֵיקָ֑ם כִּ֤י אִם עָשָׂה֙ אֶת אֲשֶׁ֣ר חָפַ֔צְתִּי וְ/הִצְלִ֖יחַ אֲשֶׁ֥ר שְׁלַחְתִּֽי/ו", "en": {"kjv": "So shall my word be that goeth forth out of my mouth: it shall not return unto me void, but it shall accomplish that which I please, and it shall prosper in the thing whereto I sent it.", "web": "so shall my word be that goes out of my mouth: it shall not return to me void, but it shall accomplish that which I please, and it shall prosper in the thing I sent it to do.", "bsb": "so My word that proceeds from My mouth will not return to Me empty, but it will accomplish what I please, and it will prosper where I send it.", "asv": "so shall my word be that goeth forth out of my mouth: it shall not return unto me void, but it shall accomplish that which I please, and it shall prosper in the thing whereto I sent it.", "ylt": "So is My word that goeth out of My mouth, It turneth not back unto Me empty, But hath done that which I desired, And prosperously effected that for which I sent it.", "dra": "So shall my word be, which shall go forth from my mouth: it shall not return to me void, but it shall do whatsoever I please, and shall prosper in the things for which I sent it.", "bbe": "So will my word be which goes out of my mouth: it will not come back to me with nothing done, but it will give effect to my purpose, and do that for which I have sent it.", "geneva": "So shall my worde be, that goeth out of my mouth: it shall not returne vnto me voyde, but it shall accomplish that which I will, and it shall prosper in the thing whereto I sent it.", "wycliffe": "so schal be my word, that schal go out of my mouth. It schal not turne ayen voide to me, but it schal do what euer thingis Y wolde, and it schal haue prosperite in these thingis to whiche Y sente it.", "rotherham": "So, shall my word be that goeth forth out of my mouth, It shall not return unto me void,—But shall accomplish that which I please, And shall prosper in that whereunto I have sent it.", "darby": "so shall my word be that goeth forth out of my mouth: it shall not return unto me void, but it shall do that which I please, and it shall accomplish that for which I send it.", "twenty": "", "jps": "So shall My word be that goeth forth out of My mouth: it shall not return unto Me void, except it accomplish that which I please, and make the thing whereto I sent it prosper.", "acv": "so shall my word be that goes forth out of my mouth. It shall not return to me void, but it shall accomplish that which I please. And it shall prosper in the thing to which I sent it.", "anderson": "", "haweis": "", "noyes": "So shall my word be, that goeth forth from my mouth; It shall not return to me void; But it shall bring to pass that which is my pleasure, And it shall accomplish that for which I send it.", "webster": "So shall my word be that proceedeth from my mouth: it shall not return to me void, but it shall accomplish that which I please, and it shall prosper [in the thing] for which I sent it.", "vulgate": "sic erit verbum meum quod egredietur de ore meo non revertetur ad me vacuum sed faciet quaecumque volui et prosperabitur in his ad quae misi illud;", "brenton": "so shall my word be, whatever shall proceed out of my mouth, it shall by no means turn back, until all the things which I willed shall have been accomplished; and I will make thy ways prosperous, and will effect my commands."}}, {"v": 12, "ref": "55:12", "o": "כִּֽי בְ/שִׂמְחָ֣ה תֵצֵ֔אוּ וּ/בְ/שָׁל֖וֹם תּֽוּבָל֑וּ/ן הֶ/הָרִ֣ים וְ/הַ/גְּבָע֗וֹת יִפְצְח֤וּ לִ/פְנֵי/כֶם֙ רִנָּ֔ה וְ/כָל עֲצֵ֥י הַ/שָּׂדֶ֖ה יִמְחֲאוּ כָֽף", "en": {"kjv": "For ye shall go out with joy, and be led forth with peace: the mountains and the hills shall break forth before you into singing, and all the trees of the field shall clap their hands.", "web": "For you shall go out with joy, and be led out with peace: the mountains and the hills shall break out before you into singing; and all the trees of the fields shall clap their hands.", "bsb": "You will indeed go out with joy and be led forth in peace; the mountains and hills will burst into song before you, and all the trees of the field will clap their hands.", "asv": "For ye shall go out with joy, and be led forth with peace: the mountains and the hills shall break forth before you into singing; and all the trees of the fields shall clap their hands.", "ylt": "For with joy ye go forth, And with peace ye are brought in, The mountains and the hills Break forth before you with singing, And all trees of the field clap the hand.", "dra": "For you shall go out with joy, and be led forth with peace: the mountains and the hills shall sing praise before you, and all the trees of the country shall clap their hands.", "bbe": "For you will go out with joy, and be guided in peace: the mountains and the hills will make melody before you, and all the trees of the fields will make sounds of joy.", "geneva": "Therefore ye shall go out with ioy, and be led forth with peace: the mountaines and the hilles shall breake foorth before you into ioye, and all the trees of the fielde shall clap their handes.", "wycliffe": "For ye schulen go out in gladnesse, and ye schulen be led forth in pees; mounteyns and litil hillis schulen synge heriynge bifore you, and alle the trees of the cuntrei schulen make ioie with hond.", "rotherham": "For with gladness shall ye come forth, And in peace, shall ye be led,—the mountains and the hills shall break out, before you, into shouts of triumph, And all the wild trees shall clap their hands:", "darby": "For ye shall go out with joy, and be led forth with peace; the mountains and the hills shall break forth before you into singing, and all the trees of the field shall clap their hands.", "twenty": "", "jps": "For ye shall go out with joy, and be led forth with peace; the mountains and the hills shall break forth before you into singing, and all the trees of the field shall clap their hands.", "acv": "For ye shall go out with joy, and be led forth with peace. The mountains and the hills shall break forth before you into singing, and all the trees of the fields shall clap their hands.", "anderson": "", "haweis": "", "noyes": "For ye shall go out with joy And be led forth with peace; The mountains and the hills shall break forth before you into singing, And all the trees of the field shall clap their hands.", "webster": "For ye shall go out with joy, and be led forth with peace: the mountains and the hills shall break forth before you into singing, and all the trees of the field shall clap [their] hands.", "vulgate": "quia in laetitia egrediemini et in pace deducemini montes et colles cantabunt coram vobis laudem et omnia ligna regionis plaudent manu;", "brenton": "For ye shall go forth with joy, and shall be taught with gladness: for the mountains and the hills shall exult to welcome you with joy, and all the trees of the field shall applaud with their branches."}}, {"v": 13, "ref": "55:13", "o": "תַּ֤חַת הַֽ/נַּעֲצוּץ֙ יַעֲלֶ֣ה בְר֔וֹשׁ תחת וְ/תַ֥חַת הַ/סִּרְפַּ֖ד יַעֲלֶ֣ה הֲדַ֑ס וְ/הָיָ֤ה לַֽ/יהוָה֙ לְ/שֵׁ֔ם לְ/א֥וֹת עוֹלָ֖ם לֹ֥א יִכָּרֵֽת", "en": {"kjv": "Instead of the thorn shall come up the fir tree, and instead of the brier shall come up the myrtle tree: and it shall be to the Lord for a name, for an everlasting sign that shall not be cut off.", "web": "Instead of the thorn shall come up the fir tree; and instead of the brier shall come up the myrtle tree: and it shall be to Yahweh for a name, for an everlasting sign that shall not be cut off.”", "bsb": "Instead of the thornbush, a cypress will grow, and instead of the brier, a myrtle will spring up; they will make a name for the LORD, an everlasting sign, never to be destroyed.”", "asv": "Instead of the thorn shall come up the fir-tree; and instead of the brier shall come up the myrtle-tree: and it shall be to Jehovah for a name, for an everlasting sign that shall not be cut off.", "ylt": "Instead of the thorn come up doth fir, Instead of the brier come up doth myrtle, And it hath been to Jehovah for a name, For a sign age-during--it is not cut off!", "dra": "Instead of the shrub, shall come up the fir tree, and instead of the nettle, shall come up the myrtle tree: and the Lord shall be named for an everlasting sign, that shall not be taken away.", "bbe": "In place of the thorn will come up the fir-tree, and in place of the blackberry the myrtle: and it will be to the Lord for a name, for an eternal sign which will not be cut off.", "geneva": "For thornes there shall grow firre trees: for nettles shall growe the myrrhe tree, and it shalbe to the Lord for a name, and for an euerlasting signe that shall not be taken away.", "wycliffe": "A fir tre schal grow for a firse, and a mirte tre schal wexe for a nettil; and the Lord schal be nemyd in to a signe euerlastynge, that schal not be doon awei.", "rotherham": "Instead of the thorn-bush, shall come up the fir-tree, And instead of the nettle, shall come up the myrtle-tree,—So shall it become unto Yahweh, a Name, A Sign age-abiding, which shall not be cut off.", "darby": "Instead of the thorn shall come up the cypress, and instead of the nettle shall come up the myrtle; and it shall be to Jehovah for a name, for an everlasting sign [that] shall not be cut off.", "twenty": "", "jps": "Instead of the thorn shall come up the cypress, and instead of the brier shall come up the myrtle; and it shall be to HaShem for a memorial, for an everlasting sign that shall not be cut off.", "acv": "Instead of the thorn shall come up the fir tree, and instead of the brier shall come up the myrtle tree. And it shall be to Jehovah for a name, for an everlasting sign that shall not be cut off.", "anderson": "", "haweis": "", "noyes": "Instead of the thorn shall grow up the cypress-tree, And instead of the bramble shall grow up the myrtle-tree, And it shall be to Jehovah for a name; For an everlasting memorial, that shall not pass away.", "webster": "Instead of the thorn shall come up the fir-tree, and instead of the brier shall come up the myrtle-tree: and it shall be to the LORD for a name, for an everlasting sign [that] shall not be cut off.", "vulgate": "pro saliunca ascendet abies et pro urtica crescet myrtus et erit Dominus nominatus in signum aeternum quod non auferetur;", "brenton": "And instead of the bramble shall come up the cypress, and instead of the nettle shall come up the myrtle: and the Lord shall be for a name, and for an everlasting sign, and shall not fail."}}]}, {"c": 56, "verses": [{"v": 1, "ref": "56:1", "o": "כֹּ֚ה אָמַ֣ר יְהוָ֔ה שִׁמְר֥וּ מִשְׁפָּ֖ט וַ/עֲשׂ֣וּ צְדָקָ֑ה כִּֽי קְרוֹבָ֤ה יְשֽׁוּעָתִ/י֙ לָ/ב֔וֹא וְ/צִדְקָתִ֖/י לְ/הִגָּלֽוֹת", "en": {"kjv": "Thus saith the Lord, Keep ye judgment, and do justice: for my salvation is near to come, and my righteousness to be revealed.", "web": "Thus says Yahweh, “Keep justice, and do righteousness; for my salvation is near to come, and my righteousness to be revealed.", "bsb": "This is what the LORD says: “Maintain justice and do what is right, for My salvation is coming soon, and My righteousness will be revealed.", "asv": "Thus saith Jehovah, Keep ye justice, and do righteousness; for my salvation is near to come, and my righteousness to be revealed.", "ylt": "Thus said Jehovah: `Keep ye judgment, and do righteousness, For near is My salvation to come, And My righteousness to be revealed.'", "dra": "Thus saith the Lord: Keep ye judgment, and do justice: for my salvation is near to come, and my justice to be revealed.", "bbe": "The Lord says, Let your way of life be upright, and let your behaviour be rightly ordered: for my salvation is near, and my righteousness will quickly be seen.", "geneva": "Thus saith the Lord, Keepe iudgement and doe iustice: for my saluation is at hand to come, and my righteousnes to be reueiled.", "wycliffe": "The Lord seith these thingis, Kepe ye doom, and do ye riytfulnesse, for whi myn helthe is niy, that it come, and my riytfulnesse, that it be schewid.", "rotherham": "Thus, saith Yahweh, Observe ye justice, And execute righteousness,—For near, is My salvation, to come in, and My righteousness to be revealed.", "darby": "Thus saith Jehovah: Keep ye judgment and do righteousness; for my salvation is near to come, and my righteousness to be revealed.", "twenty": "", "jps": "Thus saith HaShem: Keep ye justice, and do righteousness; for My salvation is near to come, and My favour to be revealed.", "acv": "Thus says Jehovah, Keep ye justice, and do righteousness. For my salvation is near to come, and my righteousness to be revealed.", "anderson": "", "haweis": "", "noyes": "Thus saith Jehovah: Keep ye justice, and practise righteousness; For the coming of my salvation is near, And my deliverance is soon to be revealed.", "webster": "Thus saith the LORD, Keep ye judgment, and do justice: for my salvation [is] near to come, and my righteousness to be revealed.", "vulgate": "haec dicit Dominus custodite iudicium et facite iustitiam quia iuxta est salus mea ut veniat et iustitia mea ut reveletur;", "brenton": "Thus saith the Lord, Keep ye judgment, and do justice: for my salvation is near to come, and my mercy to be revealed."}}, {"v": 2, "ref": "56:2", "o": "אַשְׁרֵ֤י אֱנוֹשׁ֙ יַעֲשֶׂה זֹּ֔את וּ/בֶן אָדָ֖ם יַחֲזִ֣יק בָּ֑/הּ שֹׁמֵ֤ר שַׁבָּת֙ מֵֽ/חַלְּל֔/וֹ וְ/שֹׁמֵ֥ר יָד֖/וֹ מֵ/עֲשׂ֥וֹת כָּל רָֽע", "en": {"kjv": "Blessed is the man that doeth this, and the son of man that layeth hold on it; that keepeth the sabbath from polluting it, and keepeth his hand from doing any evil.", "web": "Blessed is the man who does this, and the son of man who holds it fast; who keeps the Sabbath from profaning it, and keeps his hand from doing any evil.”", "bsb": "Blessed is the man who does this, and the son of man who holds it fast, who keeps the Sabbath without profaning it and keeps his hand from doing any evil.”", "asv": "Blessed is the man that doeth this, and the son of man that holdeth it fast; that keepeth the sabbath from profaning it, and keepeth his hand from doing any evil.", "ylt": "O the happiness of a man who doth this, And of a son of man who keepeth hold on it, Keeping the sabbath from polluting it, And keeping his hand from doing any evil.", "dra": "Blessed is the man that doth this, and the son of man that shall lay hold on this: that keepeth the sabbath from profaning it, that keepeth his hands from doing any evil.", "bbe": "Happy is the man who does this, and the son of man whose behaviour is so ordered; who keeps the Sabbath holy, and his hand from doing any evil.", "geneva": "Blessed is the man that doeth this, and the sonne of man which layeth holde on it: hee that keepeth the Sabbath and polluteth it not, and keepeth his hand from doing any euill.", "wycliffe": "Blessid is the man, that doith this, and the sone of man, that schal take this; kepynge the sabat, that he defoule not it, kepynge hise hondis, that he do not ony yuel.", "rotherham": "How happy the frail man, who doeth this! Yea the son of the earth-born who firmly graspeth it! Keeping the sabbath lest he profane it, and Keeping his own hand from doing any wrong.", "darby": "Blessed is the man that doeth this, and the son of man that holdeth fast to it; that keepeth the sabbath from profaning it, and keepeth his hand from doing any evil.", "twenty": "", "jps": "Happy is the man that doeth this, and the son of man that holdeth fast by it: that keepeth the sabbath from profaning it, and keepeth his hand from doing any evil.", "acv": "Blessed is the man who does this, and the son of man who holds it fast, who keeps the sabbath from profaning it, and keeps his hand from doing any evil.", "anderson": "", "haweis": "", "noyes": "Happy the man that doeth this, And the son of man that holdeth it fast; That keepeth the sabbath, and profaneth it not, And restraineth his hand from doing evil.", "webster": "Blessed [is] the man [that] doeth this, and the son of man [that] layeth hold on it; that keepeth the sabbath from profaning it, and keepeth his hand from doing any evil.", "vulgate": "beatus vir qui facit hoc et filius hominis qui adprehendit istud custodiens sabbatum ne polluat illud custodiens manus suas ne faciat omne malum;", "brenton": "Blessed is the man that does these things, and the man that holds by them, and keeps the sabbaths from profaning them, and keeps his hands from doing unrighteousness."}}, {"v": 3, "ref": "56:3", "o": "וְ/אַל יֹאמַ֣ר בֶּן הַ/נֵּכָ֗ר הַ/נִּלְוָ֤ה אֶל יְהוָה֙ לֵ/אמֹ֔ר הַבְדֵּ֧ל יַבְדִּילַ֛/נִי יְהוָ֖ה מֵ/עַ֣ל עַמּ֑/וֹ וְ/אַל יֹאמַר֙ הַ/סָּרִ֔יס הֵ֥ן אֲנִ֖י עֵ֥ץ יָבֵֽשׁ", "en": {"kjv": "Neither let the son of the stranger, that hath joined himself to the Lord, speak, saying, The Lord hath utterly separated me from his people: neither let the eunuch say, Behold, I am a dry tree.", "web": "Neither let the foreigner, who has joined himself to Yahweh, speak, saying, “Yahweh will surely separate me from his people”; neither let the eunuch say, “Behold, I am a dry tree.”", "bsb": "Let no foreigner who has joined himself to the LORD say, “The LORD will utterly exclude me from His people.” And let the eunuch not say, “I am but a dry tree.”", "asv": "Neither let the foreigner, that hath joined himself to Jehovah, speak, saying, Jehovah will surely separate me from his people; neither let the eunuch say, Behold, I am a dry tree.", "ylt": "Nor speak let a son of the stranger, Who is joined unto Jehovah, saying: `Jehovah doth certainly separate me from His people.' Nor say let the eunuch, `Lo, I am a tree dried up,'", "dra": "And let not the son of the stranger, that adhereth to the Lord, speak, saying: The Lord will divide and separate me from his people. And let not the eunuch say: Behold I am a dry tree.", "bbe": "And let not the man from a strange country, who has been joined to the Lord, say, The Lord will certainly put a division between me and his people: and let not the unsexed man say, See, I am a dry tree.", "geneva": "And let not the sonne of the stranger, which is ioyned to the Lord, speake and say, The Lord hath surely separate me from his people: neither let the Eunuch say, Beholde, I am a drye tree.", "wycliffe": "And seie not the sone of a comelyng, that cleueth faste to the Lord, seiynge, Bi departyng the Lord schal departe me fro his puple; and a geldyng, ether a chast man, seie not, Lo! Y am a drie tree.", "rotherham": "And let not the son of the foreigner, who hath joined himself unto Yahweh, speak, saying, Yahweh, will separate, me from his people, Neither let the eunuch, say, Lo! I, am a tree dried up!", "darby": "And let not the son of the alien, that hath joined himself to Jehovah, speak saying, Jehovah hath entirely separated me from his people; neither let the eunuch say, Behold, I am a dry tree;", "twenty": "", "jps": "Neither let the alien, that hath joined himself to HaShem, speak, saying: 'The HaShem will surely separate me from His people'; neither let the eunuch say: 'Behold, I am a dry tree.'", "acv": "Neither let the foreigner, who has joined himself to Jehovah, speak, saying, Jehovah will surely separate me from his people, nor let the eunuch say, Behold, I am a dry tree.", "anderson": "", "haweis": "", "noyes": "And let not the stranger that joineth himself to Jehovah say, Jehovah hath wholly separated me from his people. And let not the eunuch say, Behold, I am a dry tree!", "webster": "Neither let the son of the stranger, that hath joined himself to the LORD, speak, saying, The LORD hath utterly separated me from his people: neither let the eunuch say, Behold, I [am] a dry tree.", "vulgate": "et non dicat filius advenae qui adheret Domino dicens separatione dividet me Dominus a populo suo et non dicat eunuchus ecce ego lignum aridum;", "brenton": "Let not the stranger who attaches himself to the Lord, say, Surely the Lord will separate me from his people: and let not the eunuch say, I am a dry tree."}}, {"v": 4, "ref": "56:4", "o": "כִּי כֹ֣ה אָמַ֣ר יְהוָ֗ה לַ/סָּֽרִיסִים֙ אֲשֶׁ֤ר יִשְׁמְרוּ֙ אֶת שַׁבְּתוֹתַ֔/י וּ/בָֽחֲר֖וּ בַּ/אֲשֶׁ֣ר חָפָ֑צְתִּי וּ/מַחֲזִיקִ֖ים בִּ/בְרִיתִֽ/י", "en": {"kjv": "For thus saith the Lord unto the eunuchs that keep my sabbaths, and choose the things that please me, and take hold of my covenant;", "web": "For thus says Yahweh, “To the eunuchs who keep my Sabbaths, and choose the things that please me, and hold fast my covenant:", "bsb": "For this is what the LORD says: “To the eunuchs who keep My Sabbaths, who choose what pleases Me and hold fast to My covenant—", "asv": "For thus saith Jehovah of the eunuchs that keep my sabbaths, and choose the things that please me, and hold fast my covenant:", "ylt": "For thus said Jehovah of the eunuchs, Who do keep My sabbaths, And have fixed on that which I desired, And are keeping hold on My covenant:", "dra": "For thus saith the Lord to the eunuchs, They that shall keep my sabbaths, and shall choose the things that please me, and shall hold fast my covenant:", "bbe": "For the Lord says, As for the unsexed who keep my Sabbaths, and give their hearts to pleasing me, and keep their agreement with me:", "geneva": "For thus saith the Lord vnto the Eunuches, that keepe my Sabbaths, and chuse the thing that pleaseth me, and take holde of my couenant,", "wycliffe": "For the Lord seith these thingis to geldingis, that kepen my sabatis, and chesen what thingis Y wolde, and holden my boond of pees.", "rotherham": "For thus, saith Yahweh—Of the eunuchs, Who shall keep my sabbaths, And choose what I delight in,—And lay firm hold on my covenant,", "darby": "for thus saith Jehovah: Unto the eunuchs that keep my sabbaths, and choose the things that please me, and hold fast to my covenant,", "twenty": "", "jps": "For thus saith HaShem concerning the eunuchs that keep My sabbaths, and choose the things that please Me, and hold fast by My covenant:", "acv": "For thus says Jehovah of the eunuchs who keep my sabbaths, and choose the things that please me, and hold fast my covenant:", "anderson": "", "haweis": "", "noyes": "For thus saith Jehovah concerning the eunuchs: They that keep my sabbaths, And take pleasure in doing my will, And hold fast my covenant,", "webster": "For thus saith the LORD to the eunuchs that keep my sabbaths, and choose [the things] that please me, and take hold of my covenant;", "vulgate": "quia haec dicit Dominus eunuchis qui custodierint sabbata mea et elegerint quae volui et tenuerint foedus meum;", "brenton": "Thus saith the Lord to the eunuchs, as many as shall keep my sabbaths, and choose the things which I take pleasure in, and take hold of my covenant;"}}, {"v": 5, "ref": "56:5", "o": "וְ/נָתַתִּ֨י לָ/הֶ֜ם בְּ/בֵיתִ֤/י וּ/בְ/חֽוֹמֹתַ/י֙ יָ֣ד וָ/שֵׁ֔ם ט֖וֹב מִ/בָּנִ֣ים וּ/מִ/בָּנ֑וֹת שֵׁ֤ם עוֹלָם֙ אֶתֶּן ל֔/וֹ אֲשֶׁ֖ר לֹ֥א יִכָּרֵֽת", "en": {"kjv": "Even unto them will I give in mine house and within my walls a place and a name better than of sons and of daughters: I will give them an everlasting name, that shall not be cut off.", "web": "to them I will give in my house and within my walls a memorial and a name better than of sons and of daughters; I will give them an everlasting name, that shall not be cut off.", "bsb": "I will give them, in My house and within My walls, a memorial and a name better than that of sons and daughters. I will give them an everlasting name that will not be cut off.", "asv": "Unto them will I give in my house and within my walls a memorial and a name better than of sons and of daughters; I will give them an everlasting name, that shall not be cut off.", "ylt": "I have given to them in My house, And within My walls a station and a name, Better than sons and than daughters, A name age-during I give to him That is not cut off.", "dra": "I will give to them in my house, and within my walls, a place, and a name better than sons and daughters: I will give them an everlasting name which shall never perish.", "bbe": "I will give to them in my house, and inside my walls, a place and a name better than that of sons and daughters; I will give them an eternal name which will not be cut off.", "geneva": "Euen vnto them wil I giue in mine House and within my walles, a place and a name better then of the sonnes and of the daughters: I will giue them an euerlasting name, that shall not be put out.", "wycliffe": "Y schal yyue to hem a place in myn hous, and in my wallis, and the beste name of sones and douytris; Y schal yyue to hem a name euerlastynge, that schal not perische.", "rotherham": "That I will give unto them—In my house, And within my walls, A sign and a name, better than sons and daughters,—A name age-abiding, will I give him, which shall not be cut off.", "darby": "even unto them will I give in my house and within my walls a place and a name better than of sons and daughters; I will give them an everlasting name, that shall not be cut off.", "twenty": "", "jps": "Even unto them will I give in My house and within My walls a monument and a memorial better than sons and daughters; I will give them an everlasting memorial, that shall not be cut off.", "acv": "To them I will give in my house and within my walls a memorial and a name better than of sons and of daughters. I will give them an everlasting name, that shall not be cut off.", "anderson": "", "haweis": "", "noyes": "To them will I give in my house, and within my walls, a portion and a name, Better than of sons and daughters; An everlasting name will I give them, That shall never fade away.", "webster": "Even to them will I give in my house and within my walls a place and a name better than of sons and of daughters: I will give them an everlasting name, that shall not be cut off.", "vulgate": "dabo eis in domo mea et in muris meis locum et nomen melius a filiis et filiabus nomen sempiternum dabo eis quod non peribit;", "brenton": "I will give to them in my house and within my walls an honourable place, better than sons and daughters: I will give them an everlasting name, and it shall not fail."}}, {"v": 6, "ref": "56:6", "o": "וּ/בְנֵ֣י הַ/נֵּכָ֗ר הַ/נִּלְוִ֤ים עַל יְהוָה֙ לְ/שָׁ֣רְת֔/וֹ וּֽ/לְ/אַהֲבָה֙ אֶת שֵׁ֣ם יְהוָ֔ה לִ/הְי֥וֹת ל֖/וֹ לַ/עֲבָדִ֑ים כָּל שֹׁמֵ֤ר שַׁבָּת֙ מֵֽ/חַלְּל֔/וֹ וּ/מַחֲזִיקִ֖ים בִּ/בְרִיתִֽ/י", "en": {"kjv": "Also the sons of the stranger, that join themselves to the Lord, to serve him, and to love the name of the Lord, to be his servants, every one that keepeth the sabbath from polluting it, and taketh hold of my covenant;", "web": "Also the foreigners who join themselves to Yahweh, to minister to him, and to love Yahweh’s name, to be his servants, everyone who keeps the Sabbath from profaning it, and holds fast my covenant;", "bsb": "And the foreigners who join themselves to the LORD to minister to Him, to love the name of the LORD, and to be His servants— all who keep the Sabbath without profaning it and who hold fast to My covenant—", "asv": "Also the foreigners that join themselves to Jehovah, to minister unto him, and to love the name of Jehovah, to be his servants, every one that keepeth the sabbath from profaning it, and holdeth fast my covenant;", "ylt": "And sons of the stranger, who are joined to Jehovah, To serve Him, and to love the name of Jehovah, To be to Him for servants, Every keeper of the sabbath from polluting it, And those keeping hold on My covenant.", "dra": "And the children of the stranger that adhere to the Lord, to worship him, and to love his name, to be his servants: every one that keepeth the sabbath from profaning it, and that holdeth fast my covenant:", "bbe": "And as for those from a strange country, who are joined to the Lord, to give worship to him and honour to his name, to be his servants, even everyone who keeps the Sabbath holy, and keeps his agreement with me:", "geneva": "Also the strangers that cleaue vnto the Lord, to serue him, and to loue the Name of the Lord, and to be his seruants: euery one that keepeth the Sabbath, and polluteth it not and imbraceth my couenant,", "wycliffe": "And Y schal brynge in to blis the sones of a comelyng, that cleuen faste to the Lord, that thei worschipe hym, and loue his name, that thei be to hym in to seruauntis; ech man kepynge the sabat, that he defoule it not, and holdynge my boond of pees;", "rotherham": "And, as for the sons of the foreigner—Who have joined themselves unto Yahweh To wait upon him, and To love the name of Yahweh, To become his for servants,—Every one who keepeth the sabbath, lest he profane it. And who, layeth firm hold on my covenant,", "darby": "Also the sons of the alien, that join themselves to Jehovah, to minister unto him and to love the name of Jehovah, to be his servants, every one that keepeth the sabbath from profaning it, and holdeth fast to my covenant;", "twenty": "", "jps": "Also the aliens, that join themselves to HaShem, to minister unto Him, and to love the name of HaShem, to be His servants, every one that keepeth the sabbath from profaning it, and holdeth fast by My covenant:", "acv": "Also the foreigners who join themselves to Jehovah, to minister to him, and to love the name of Jehovah, to be his servants, everyone who keeps the sabbath from profaning it, and holds fast my covenant,", "anderson": "", "haweis": "", "noyes": "The strangers, also, that join themselves to Jehovah, to serve him, To love the name of Jehovah, and to be his servants. Every one that keepeth the sabbath, and profaneth it not, And holdeth fast my covenant,", "webster": "Also the sons of the stranger, that join themselves to the LORD, to serve him, and to love the name of the LORD, to be his servants, every one that keepeth the sabbath from profaning it, and taketh hold of my covenant;", "vulgate": "et filios advenae qui adherent Domino ut colant eum et diligant nomen eius ut sint ei in servos omnem custodientem sabbatum ne polluat illud et tenentem foedus meum;", "brenton": "And I will give it to the strangers that attach themselves to the Lord, to serve him, and to love the name of the Lord, to be to him servants and handmaids; and as for all that keep my sabbaths from profaning them, and that take hold of my covenant;"}}, {"v": 7, "ref": "56:7", "o": "וַ/הֲבִיאוֹתִ֞י/ם אֶל הַ֣ר קָדְשִׁ֗/י וְ/שִׂמַּחְתִּי/ם֙ בְּ/בֵ֣ית תְּפִלָּתִ֔/י עוֹלֹתֵי/הֶ֧ם וְ/זִבְחֵי/הֶ֛ם לְ/רָצ֖וֹן עַֽל מִזְבְּחִ֑/י כִּ֣י בֵיתִ֔/י בֵּית תְּפִלָּ֥ה יִקָּרֵ֖א לְ/כָל הָ/עַמִּֽים", "en": {"kjv": "Even them will I bring to my holy mountain, and make them joyful in my house of prayer: their burnt offerings and their sacrifices shall be accepted upon mine altar; for mine house shall be called an house of prayer for all people.", "web": "even them will I bring to my holy mountain, and make them joyful in my house of prayer: their burnt offerings and their sacrifices shall be accepted on my altar; for my house shall be called a house of prayer for all peoples.”", "bsb": "I will bring them to My holy mountain and make them joyful in My house of prayer. Their burnt offerings and sacrifices will be accepted on My altar, for My house will be called a house of prayer for all the nations.”", "asv": "even them will I bring to my holy mountain, and make them joyful in my house of prayer: their burnt-offerings and their sacrifices shall be accepted upon mine altar; for my house shall be called a house of prayer for all peoples.", "ylt": "I have brought them unto My holy mountain, And caused them to rejoice in My house of prayer, Their burnt-offerings and their sacrifices Are for a pleasing thing on Mine altar, For My house, `A house of prayer,' Is called for all the peoples.", "dra": "I will bring them into my holy mount, and will make them joyful in my house of prayer: their holocausts, and their victims shall please me upon my altar: for my house shall be called the house of prayer, for all nations.", "bbe": "I will make them come to my holy mountain, and will give them joy in my house of prayer; I will take pleasure in the burned offerings which they make on my altar: for my house will be named a house of prayer for all peoples.", "geneva": "Them wil I bring also to mine holy mountaine, and make them ioyfull in mine House of prayer: their burnt offerings and their sacrifices shall be accepted vpon mine altar: for mine House shall be called an house of prayer for all people.", "wycliffe": "Y schal brynge hem in to myn hooli hil, and Y schal make hem glad in the hous of my preier; her brent sacrifices and her slayn sacrifices schulen plese me on my auter; for whi myn hous schal be clepid an hous of preier to alle puplis,", "rotherham": "Surely I will bring them into my holy mountain And make them joyful in my house of prayer, Their ascending-offerings and their sacrifices, being accepted upon mine altar,—For, my house, a house of prayer, shall be called, for all the peoples!", "darby": "even them will I bring to my holy mountain, and make them joyful in my house of prayer; their burnt-offerings and their sacrifices shall be accepted upon mine altar: for my house shall be called a house of prayer for all the peoples.", "twenty": "", "jps": "Even them will I bring to My holy mountain, and make them joyful in My house of prayer; their burnt-offerings and their sacrifices shall be acceptable upon Mine altar; for My house shall be called a house of prayer for all peoples.", "acv": "even them I will bring to my holy mountain, and make them joyful in my house of prayer. Their burnt offerings and their sacrifices shall be accepted upon my altar, for my house shall be called a house of prayer for all peoples.", "anderson": "", "haweis": "", "noyes": "Them will I bring to my holy mountain, And I will make them rejoice in my house of prayer; Their burnt-offerings and sacrifices shall be accepted on mine altar; For my house shall be called a house of prayer for all nations.", "webster": "Even them will I bring to my holy mountain, and make them joyful in my house of prayer: their burnt-offerings and their sacrifices [shall be] accepted upon my altar; for my house shall be called a house of prayer for all people.", "vulgate": "adducam eos in montem sanctum meum et laetificabo eos in domo orationis meae holocausta eorum et victimae eorum placebunt mihi super altari meo quia domus mea domus orationis vocabitur cunctis populis;", "brenton": "I will bring them to my holy mountain, and gladden them in my house of prayer: their whole-burnt-offerings and their sacrifices shall be acceptable upon mine altar; for my house shall be called a house of prayer for all nations,"}}, {"v": 8, "ref": "56:8", "o": "נְאֻם֙ אֲדֹנָ֣/י יְהוִ֔ה מְקַבֵּ֖ץ נִדְחֵ֣י יִשְׂרָאֵ֑ל ע֛וֹד אֲקַבֵּ֥ץ עָלָ֖י/ו לְ/נִקְבָּצָֽי/ו", "en": {"kjv": "The Lord God which gathereth the outcasts of Israel saith, Yet will I gather others to him, beside those that are gathered unto him.", "web": "The Lord Yahweh, who gathers the outcasts of Israel, says, “Yet will I gather others to him, besides his own who are gathered.”", "bsb": "Thus declares the Lord GOD, who gathers the dispersed of Israel: “I will gather to them still others besides those already gathered.”", "asv": "The Lord Jehovah, who gathereth the outcasts of Israel, saith, Yet will I gather others to him, besides his own that are gathered.", "ylt": "An affirmation of the Lord Jehovah, Who is gathering the outcasts of Israel: `Again I gather to him--to his gathered ones.'", "dra": "The Lord God, who gathereth the scattered of Israel, saith: I will still gather unto him his congregation.", "bbe": "The Lord God, who gets together the wandering ones of Israel, says, I will get together others in addition to those of Israel who have come back.", "geneva": "The Lord God sayth, which gathereth the scattered of Israel, Yet wil I gather to them those that are to be gathered to them.", "wycliffe": "seith the Lord God, that gaderith togidere the scaterid men of Israel. Yit Y schal gadere togidere to hym alle the gaderid men therof.", "rotherham": "Declareth My Lord, Yahweh, Who is gathering the outcasts of Israel:—Yet others, will I gather unto him Besides his own gathered ones.", "darby": "The Lord Jehovah, who gathereth the outcasts of Israel, saith: Yet will I gather [others] to him, with those of his that are gathered.", "twenty": "", "jps": "Saith the L-rd GOD who gathereth the dispersed of Israel: yet I will gather others to him, beside those of him that are gathered.", "acv": "The lord Jehovah, who gathers the outcasts of Israel, says, Yet I will gather to him, besides his own who are gathered.", "anderson": "", "haweis": "", "noyes": "Thus saith the Lord Jehovah, That gathereth the outcasts of Israel; Yet will I gather others to him, Besides those that are already gathered.", "webster": "The Lord GOD who gathereth the outcasts of Israel, Yet will I gather [others] to him, besides those that are gathered to him.", "vulgate": "ait Dominus Deus qui congregat dispersos Israhel adhuc congregabo ad eum congregatos eius;", "brenton": "saith the Lord that gathers the dispersed of Israel; for I will gather to him a congregation."}}, {"v": 9, "ref": "56:9", "o": "כֹּ֖ל חַיְת֣וֹ שָׂדָ֑י אֵתָ֕יוּ לֶ/אֱכֹ֥ל כָּל חַיְת֖וֹ בַּ/יָּֽעַר", "en": {"kjv": "All ye beasts of the field, come to devour, yea, all ye beasts in the forest.", "web": "All you animals of the field, come to devour, all you animals in the forest.", "bsb": "Come, all you beasts of the field; eat greedily, all you beasts of the forest.", "asv": "All ye beasts of the field, come to devour, yea, all ye beasts in the forest.", "ylt": "Every beast of the field, Come to devour, every beast in the forest.", "dra": "All ye beasts of the field come to devour, all ye beasts of the forest.", "bbe": "All you beasts of the field, come together for your meat, even all you beasts of the wood.", "geneva": "All ye beastes of the fielde, come to deuoure, euen all ye beastes of the forest.", "wycliffe": "Alle beestis of the feeld, come ye to deuoure, alle beestis of the forest.", "rotherham": "All ye beasts of the field! come ye to devour, All ye beasts in the forest.", "darby": "All ye beasts of the field, come to devour, all ye beasts in the forest.", "twenty": "", "jps": "All ye beasts of the field, come to devour, yea, all ye beasts in the forest.", "acv": "All ye beasts of the field, come to devour, yea, all ye beasts in the forest.", "anderson": "", "haweis": "", "noyes": "Come, all ye beasts of the field, Yea, all ye beasts of the forest, to devour!", "webster": "All ye beasts of the field, come to devour, yes, all ye beasts in the forest.", "vulgate": "omnes bestiae agri venite ad devorandum universae bestiae saltus;", "brenton": "All ye beasts of the field, come, devour, all ye beasts of the forest."}}, {"v": 10, "ref": "56:10", "o": "צפו צֹפָ֞י/ו עִוְרִ֤ים כֻּלָּ/ם֙ לֹ֣א יָדָ֔עוּ כֻּלָּ/ם֙ כְּלָבִ֣ים אִלְּמִ֔ים לֹ֥א יוּכְל֖וּ לִ/נְבֹּ֑חַ הֹזִים֙ שֹֽׁכְבִ֔ים אֹהֲבֵ֖י לָ/נֽוּם", "en": {"kjv": "His watchmen are blind: they are all ignorant, they are all dumb dogs, they cannot bark; sleeping, lying down, loving to slumber.", "web": "His watchmen are blind, they are all without knowledge; they are all mute dogs, they can’t bark; dreaming, lying down, loving to slumber.", "bsb": "Israel’s watchmen are blind, they are all oblivious; they are all mute dogs, they cannot bark; they are dreamers lying around, loving to slumber.", "asv": "His watchmen are blind, they are all without knowledge; they are all dumb dogs, they cannot bark; dreaming, lying down, loving to slumber.", "ylt": "Blind are his watchmen--all of them, They have not known, All of them are dumb dogs, they are not able to bark, Dozing, lying down, loving to slumber.", "dra": "His watchmen are all blind, they are all ignorant: dumb dogs not able to bark, seeing vain things, sleeping and loving dreams.", "bbe": "His watchmen are blind, they are all without knowledge; they are all dogs without tongues, unable to make a sound; stretched out dreaming, loving sleep.", "geneva": "Their watchmen are all blinde: they haue no knowledge: they are all dumme dogs: they can not barke: they lie and sleepe and delite in sleeping.", "wycliffe": "Alle the biholderis therof ben blinde, alle thei knewen not; doumbe doggis, that moun not berke, seynge veyn thingis, slepynge, and louynge dremes;", "rotherham": "His watchmen, are blind None of them, know, All of them, are dumb dogs, they cannot bark,—Dreaming, sleeping, loving to slumber.", "darby": "His watchmen are all of them blind, they are without knowledge; they are all dumb dogs that cannot bark, dreaming, lying down, loving to slumber:", "twenty": "", "jps": "His watchmen are all blind, without knowledge; they are all dumb dogs, they cannot bark; raving, lying down, loving to slumber.", "acv": "His watchmen are blind. They are all without knowledge. They are all mute dogs. They cannot bark, dreaming, lying down, loving to slumber.", "anderson": "", "haweis": "", "noyes": "His watchmen are all blind; they know nothing; They are all dumb dogs, that cannot bark, Dreaming, lying down, loving to slumber;", "webster": "His watchmen [are] blind: they are all ignorant, they [are] all dumb dogs, they cannot bark; sleeping, lying down, loving to slumber.", "vulgate": "speculatores eius caeci omnes nescierunt universi canes muti non valentes latrare videntes vana dormientes et amantes somnia;", "brenton": "See how they are all blinded: they have not known; they are dumb dogs that will not bark; dreaming of rest, loving to slumber."}}, {"v": 11, "ref": "56:11", "o": "וְ/הַ/כְּלָבִ֣ים עַזֵּי נֶ֗פֶשׁ לֹ֤א יָֽדְעוּ֙ שָׂבְעָ֔ה וְ/הֵ֣מָּה רֹעִ֔ים לֹ֥א יָדְע֖וּ הָבִ֑ין כֻּלָּ/ם֙ לְ/דַרְכָּ֣/ם פָּנ֔וּ אִ֥ישׁ לְ/בִצְע֖/וֹ מִ/קָּצֵֽ/הוּ", "en": {"kjv": "Yea, they are greedy dogs which can never have enough, and they are shepherds that cannot understand: they all look to their own way, every one for his gain, from his quarter.", "web": "Yes, the dogs are greedy, they can never have enough; and these are shepherds who can’t understand: they have all turned to their own way, each one to his gain, from every quarter.", "bsb": "Like ravenous dogs, they are never satisfied. They are shepherds with no discernment; they all turn to their own way, each one seeking his own gain:", "asv": "Yea, the dogs are greedy, they can never have enough; and these are shepherds that cannot understand: they have all turned to their own way, each one to his gain, from every quarter.", "ylt": "And the dogs are strong of desire, They have not known sufficiency, And they are shepherds! They have not known understanding, All of them to their own way they did turn, Each to his dishonest gain from his quarter:", "dra": "And most impudent dogs, they never had enough: the shepherds themselves knew no understanding: all have turned aside into their own way, every one after his own gain, from the first even to the last.", "bbe": "Yes, the dogs are for ever looking for food; while these, the keepers of the sheep, are without wisdom: they have all gone after their pleasure, every one looking for profit; they are all the same.", "geneva": "And these griedy dogs can neuer haue ynough: and these shepheards cannot vnderstand: for they all looke to their owne way, euery one for his aduantage, and for his owne purpose.", "wycliffe": "and moost vnschamefast doggis knewen not fulnesse. Tho scheepherdis knewen not vndurstondyng; alle thei bowyden in to her weie, ech man to his aueryce, fro the hiyeste `til to the laste.", "rotherham": "And, the dogs, are greedy they know not to be satisfied. Yea, they, are shepherds who know not to discern,—All of them unto their own way, have turned, Every man to his unjust gain, on every hand:", "darby": "and the dogs are greedy, they know not to be satisfied, and these are shepherds that know not how to discern: they all turn to their own way, every one for his gain, even to the last of them:", "twenty": "", "jps": "Yea, the dogs are greedy, they know not when they have enough; and these are shepherds that cannot understand; they all turn to their own way, each one to his gain, one and all.", "acv": "Yea, the dogs are greedy; they can never have enough. And these are shepherds who cannot understand. They have all turned to their own way, each one to his gain, from every quarter.", "anderson": "", "haweis": "", "noyes": "Yet are they greedy dogs that cannot be satisfied; The shepherds themselves will not attend; They all turn aside to their own way, Every one of them to their own gain.", "webster": "Yes, [they are] greedy dogs [which] can never have enough, and they [are] shepherds [that] cannot understand: they all look to their own way, every one for his gain, from his quarter.", "vulgate": "et canes inpudentissimi nescierunt saturitatem ipsi pastores ignoraverunt intellegentiam omnes in viam suam declinaverunt unusquisque ad avaritiam suam a summo usque ad novissimum;", "brenton": "Yea, they are insatiable dogs, that know not what it is to be filled, and they are wicked, having no understanding: all have followed their own ways, each according to his will."}}, {"v": 12, "ref": "56:12", "o": "אֵתָ֥יוּ אֶקְחָה יַ֖יִן וְ/נִסְבְּאָ֣ה שֵׁכָ֑ר וְ/הָיָ֤ה כָ/זֶה֙ י֣וֹם מָחָ֔ר גָּד֖וֹל יֶ֥תֶר מְאֹֽד", "en": {"kjv": "Come ye, say they, I will fetch wine, and we will fill ourselves with strong drink; and to morrow shall be as this day, and much more abundant.", "web": "“Come,” say they, “I will get wine, and we will fill ourselves with strong drink; and tomorrow shall be as this day, great beyond measure.”", "bsb": "“Come, let me get the wine, let us imbibe the strong drink, and tomorrow will be like today, only far better!”", "asv": "Come ye, say they, I will fetch wine, and we will fill ourselves with strong drink; and to-morrow shall be as this day, a day great beyond measure.", "ylt": "`Come ye, I take wine, And we drink, quaff strong drink, And as this day hath been to-morrow, Great--exceeding abundant!'", "dra": "Come, let us take wine, and be filled with drunkenness: and it shall be as to day, so also to morrow, and much more.", "bbe": "Come, they say, I will get wine, and we will take strong drink in full measure; and tomorrow will be like today, full of pleasure.", "geneva": "Come, I wil bring wine, and we wil fill our selues with strong drinke, and to morowe shalbe as this day, and much more abundant.", "wycliffe": "Come ye, take we wyn, and be we fillid of drunkenesse; and it schal be as to dai, so and to morewe, and myche more.", "rotherham": "Come ye! I will fetch wine Let us fill ourselves with strong drink,—And like this day, shall, to-morrow be—Great beyond measure!", "darby": "Come, [say they,] I will fetch wine, and we will fill ourselves with strong drink; and to-morrow shall be as this day, [and] much more abundant.", "twenty": "", "jps": "'Come ye, I will fetch wine, and we will fill ourselves with strong drink; and to-morrow shall be as this day, and much more abundant.'", "acv": "Come ye, they say, I will fetch wine, and we will fill ourselves with strong drink. And tomorrow shall be as this day, great beyond measure.", "anderson": "", "haweis": "", "noyes": "\"Come on, let me bring wine, And let us fill ourselves with strong drink, And to-morrow shall be as to-day, And even much more abundant.\"", "webster": "Come ye, [say they], I will bring wine, and we will fill ourselves with strong drink; and to-morrow shall be as this day, [and] much more abundant.", "vulgate": "venite sumamus vinum et impleamur ebrietate et erit sicut hodie sic et cras et multo amplius;", "brenton": ""}}]}, {"c": 57, "verses": [{"v": 1, "ref": "57:1", "o": "הַ/צַּדִּ֣יק אָבָ֔ד וְ/אֵ֥ין אִ֖ישׁ שָׂ֣ם עַל לֵ֑ב וְ/אַנְשֵׁי חֶ֤סֶד נֶֽאֱסָפִים֙ בְּ/אֵ֣ין מֵבִ֔ין כִּֽי מִ/פְּנֵ֥י הָ/רָעָ֖ה נֶאֱסַ֥ף הַ/צַּדִּֽיק", "en": {"kjv": "The righteous perisheth, and no man layeth it to heart: and merciful men are taken away, none considering that the righteous is taken away from the evil to come.", "web": "The righteous perishes, and no man lays it to heart; and merciful men are taken away, no one considering that the righteous is taken away from the evil.", "bsb": "The righteous perish, and no one takes it to heart; devout men are swept away, while no one considers that the righteous are guided from the presence of evil.", "asv": "The righteous perisheth, and no man layeth it to heart; and merciful men are taken away, none considering that the righteous is taken away from the evil to come.", "ylt": "The righteous hath perished, And there is none laying it to heart, And men of kindness are gathered, Without any considering that from the face of evil Gathered is the righteous one.", "dra": "The just perisheth, and no man layeth it to heart, and men of mercy are taken away, because there is none that understandeth; for the just man is taken away from before the face of evil.", "bbe": "The upright man goes to his death, and no one gives a thought to it; and god-fearing men are taken away, and no one is troubled by it; for the upright man is taken away because of evil-doing, and goes into peace.", "geneva": "The righteous perisheth, and no man considereth it in heart: and mercifull men are taken away, and no man vnderstandeth that the righteous is taken away from the euill to come.", "wycliffe": "A iust man perischith, and noon is, that thenkith in his herte; and men of merci ben gaderid togidere, for noon is that vndurstondith; for whi a iust man is gaderid fro the face of malice.", "rotherham": "The righteous one, hath perished, And not a man, hath taken it to heart—Yea the men of lovingkindness, have been withdrawn No one considering, That from the presence of calamity, hath the righteous been withdrawn.", "darby": "The righteous perisheth, and no man layeth it to heart; and merciful men are taken away, none considering that the righteous is taken away from before the evil.", "twenty": "", "jps": "The righteous perisheth, and no man layeth it to heart, and godly men are taken away, none considering that the righteous is taken away from the evil to come.", "acv": "The righteous man perishes, and no man lays it to heart. And merciful men are taken away; none considering that the righteous man is taken away from the evil.", "anderson": "", "haweis": "", "noyes": "The righteous man perisheth, and no one layeth it to heart; And pious men are taken away, and none considereth That because of the evil the righteous man is taken away.", "webster": "The righteous perisheth, and no man layeth [it] to heart: and merciful men [are] taken away, none considering that the righteous is taken away from the evil [to come].", "vulgate": "iustus perit et nemo est qui recogitet in corde suo et viri misericordiae colliguntur quia non est qui intellegat a facie enim malitiae collectus est iustus;", "brenton": "See how the just man has perished, and no one lays it to heart: and righteous men are taken away, and no one considers: for the righteous has been removed out of the way of injustice."}}, {"v": 2, "ref": "57:2", "o": "יָב֣וֹא שָׁל֔וֹם יָנ֖וּחוּ עַל מִשְׁכְּבוֹתָ֑/ם הֹלֵ֖ךְ נְכֹחֽ/וֹ", "en": {"kjv": "He shall enter into peace: they shall rest in their beds, each one walking in his uprightness.", "web": "He enters into peace; they rest in their beds, each one who walks in his uprightness.", "bsb": "Those who walk uprightly enter into peace; they find rest, lying down in death.", "asv": "He entereth into peace; they rest in their beds, each one that walketh in his uprightness.", "ylt": "He entereth into peace, they rest on their beds, Each is going straightforward.", "dra": "Let peace come, let him rest in his bed that hath walked in his uprightness.", "bbe": "They are at rest in their last resting-places, every one going straight before him.", "geneva": "Peace shall come: they shall rest in their beds, euery one that walketh before him.", "wycliffe": "Pees come, reste he in his bed, that yede in his dressyng.", "rotherham": "He entereth into peace, Let them rest upon their couches,—Each one who went on a straight path.", "darby": "He entereth into peace: they rest in their beds, [each one] that hath walked in his uprightness.", "twenty": "", "jps": "He entereth into peace, they rest in their beds, each one that walketh in his uprightness.", "acv": "He enters into peace. They rest in their beds, each one who walks in his uprightness.", "anderson": "", "haweis": "", "noyes": "He entereth into peace; He resteth in his bed, Every one that walketh in uprightness.", "webster": "He shall enter into peace: they shall rest in their beds, [each one] walking [in] his uprightness.", "vulgate": "veniat pax requiescat in cubili suo qui ambulavit in directione sua;", "brenton": "His burial shall be in peace: he has been removed out of the way."}}, {"v": 3, "ref": "57:3", "o": "וְ/אַתֶּ֥ם קִרְבוּ הֵ֖נָּה בְּנֵ֣י עֹנְנָ֑ה זֶ֥רַע מְנָאֵ֖ף וַ/תִּזְנֶֽה", "en": {"kjv": "But draw near hither, ye sons of the sorceress, the seed of the adulterer and the whore.", "web": "“But draw near here, you sons of the sorceress, the seed of the adulterer and the prostitute.", "bsb": "“But come here, you sons of a sorceress, you offspring of adulterers and prostitutes!", "asv": "But draw near hither, ye sons of the sorceress, the seed of the adulterer and the harlot.", "ylt": "And ye, come near hither, O sons of a sorceress, seed of an adulterer, Even thou dost commit whoredom.", "dra": "But draw near hither, you sons of the sorceress, the seed of the adulterer, and of the harlot.", "bbe": "But come near, you sons of her who is wise in secret arts, the seed of her who is false to her husband, and of the loose woman.", "geneva": "But you witches children, come hither, the seede of the adulterer and of the whore.", "wycliffe": "But ye, sones of the sekere of fals dyuynyng bi chiteryng of briddys, neiye hidur, the seed of auowtresse, and of an hoore.", "rotherham": "But, ye, …draw near hither, Ye sons of divination,—Ye seed of an adulterer when your mother committed unchastity!", "darby": "But draw near hither, ye sons of the sorceress, the seed of the adulterer and the harlot.", "twenty": "", "jps": "But draw near hither, ye sons of the sorceress, the seed of the adulterer and the harlot.", "acv": "But draw near here, ye sons of the sorceress, the seed of the adulterer and the harlot.", "anderson": "", "haweis": "", "noyes": "But draw near hither, ye sons of the sorceress, Ye brood of the adulterer and the harlot!", "webster": "But draw near hither, ye sons of the sorceress, the seed of the adulterer and the lewd.", "vulgate": "vos autem accedite huc filii auguratricis semen adulteri et fornicariae;", "brenton": "But draw ye near hither, ye lawless children, the seed of adulterers and the harlot."}}, {"v": 4, "ref": "57:4", "o": "עַל מִי֙ תִּתְעַנָּ֔גוּ עַל מִ֛י תַּרְחִ֥יבוּ פֶ֖ה תַּאֲרִ֣יכוּ לָשׁ֑וֹן הֲ/לֽוֹא אַתֶּ֥ם יִלְדֵי פֶ֖שַׁע זֶ֥רַע שָֽׁקֶר", "en": {"kjv": "Against whom do ye sport yourselves? against whom make ye a wide mouth, and draw out the tongue? are ye not children of transgression, a seed of falsehood,", "web": "Against whom do you sport yourselves? Against whom do you make a wide mouth, and stick out your tongue? Aren’t you children of disobedience, a seed of falsehood,", "bsb": "Whom are you mocking? At whom do you snarl and stick out your tongue? Are you not children of transgression, offspring of deceit,", "asv": "Against whom do ye sport yourselves? against whom make ye a wide mouth, and put out the tongue? are ye not children of transgression, a seed of falsehood,", "ylt": "Against whom do ye sport yourselves? Against whom enlarge ye the mouth? Prolong ye the tongue? Are not ye children of transgression? a false seed?", "dra": "Upon whom have you jested? upon whom have you opened your mouth wide, and put out your tongue? are not you wicked children, a false seed,", "bbe": "Of whom do you make sport? against whom is your mouth open wide and your tongue put out? are you not uncontrolled children, a false seed,", "geneva": "On whome haue ye iested? vpon whome haue ye gaped and thrust out your tongue? are not ye rebellious children, and a false seede?", "wycliffe": "On whom scorneden ye? on whom maden ye greet the mouth, and puttiden out the tunge? Whethir ye ben not cursid sones, a seed of leesyngis?", "rotherham": "Against whom would ye disport yourselves? Against whom would ye widen the mouth and lengthen the tongue,—Are not, ye, Children of transgression, A Seed of falsehood.", "darby": "Against whom do ye sport yourselves? Against whom do ye make a wide mouth, [and] draw out the tongue? Are ye not children of transgression, a seed of falsehood,", "twenty": "", "jps": "Against whom do ye sport yourselves? Against whom make ye a wide mouth, and draw out the tongue? Are ye not children of transgression, a seed of falsehood,", "acv": "Against whom do ye sport yourselves, against whom ye make a wide mouth, and put out the tongue? Are ye not children of transgression, a seed of falsehood,", "anderson": "", "haweis": "", "noyes": "Of whom do ye make your sport, And at whom do ye make wide the mouth, And draw out the tongue? Are ye not rebellious children, a treacherous brood?", "webster": "Against whom do ye sport yourselves? against whom make ye a wide mouth, [and] thrust out the tongue? [are] ye not children of transgression, a seed of falsehood,", "vulgate": "super quem lusistis super quem dilatastis os et eiecistis linguam numquid non vos filii scelesti semen mendax;", "brenton": "Wherein have ye been rioting? and against whom have ye opened your mouth, and against whom have ye loosed your tongue? are ye not children of perdition? a lawless seed?"}}, {"v": 5, "ref": "57:5", "o": "הַ/נֵּֽחָמִים֙ בָּֽ/אֵלִ֔ים תַּ֖חַת כָּל עֵ֣ץ רַעֲנָ֑ן שֹׁחֲטֵ֤י הַ/יְלָדִים֙ בַּ/נְּחָלִ֔ים תַּ֖חַת סְעִפֵ֥י הַ/סְּלָעִֽים", "en": {"kjv": "Enflaming yourselves with idols under every green tree, slaying the children in the valleys under the clifts of the rocks?", "web": "you who inflame yourselves among the oaks, under every green tree; who kill the children in the valleys, under the clefts of the rocks?", "bsb": "who burn with lust among the oaks, under every luxuriant tree, who slaughter your children in the valleys, under the clefts of the rocks?", "asv": "ye that inflame yourselves among the oaks, under every green tree; that slay the children in the valleys, under the clefts of the rocks?", "ylt": "Who are inflamed among oaks, under every green tree, Slaughtering the children in valleys, Under clefts of the rocks.", "dra": "Who seek your comfort in idols under every green tree, sacrificing children in the torrents, under the high rocks?", "bbe": "You who are burning with evil desire among the oaks, under every green tree; putting children to death in the valleys, under the cracks of the rocks?", "geneva": "Inflamed with idoles vnder euery greene tree? and sacrificing the children in the valleys vnder the tops of the rocks?", "wycliffe": "which ben coumfortid in goddis, vndur ech tree ful of bowis, and offren litle children in strondis, vndur hiye stoonys.", "rotherham": "Who inflame yourselves With the terebinths, Under every green tree—Slaying the children, In the torrent-valleys, Under the clefts of the crags:", "darby": "inflaming yourselves with idols under every green tree, slaying the children in the valleys under the clefts of the rocks?", "twenty": "", "jps": "Ye that inflame yourselves among the terebinths, under every leafy tree; that slay the children in the valleys, under the clefts of the rocks?", "acv": "ye who inflame yourselves among the oaks, under every green tree, who kill the children in the valleys, under the clefts of the rocks?", "anderson": "", "haweis": "", "noyes": "Burning with lust for idols Under every green tree, Slaying children in the valleys, Under the clefts of the rocks?", "webster": "Inflaming yourselves with idols under every green tree, slaying the children in the valleys under the cliffs of the rocks?", "vulgate": "qui consolamini in diis subter omne lignum frondosum immolantes parvulos in torrentibus subter inminentes petras;", "brenton": "who call upon idols under the leafy trees, slaying your children in the valleys among the rocks?"}}, {"v": 6, "ref": "57:6", "o": "בְּ/חַלְּקֵי נַ֣חַל חֶלְקֵ֔/ךְ הֵ֥ם הֵ֖ם גּוֹרָלֵ֑/ךְ גַּם לָ/הֶ֞ם שָׁפַ֥כְתְּ נֶ֨סֶךְ֙ הֶעֱלִ֣ית מִנְחָ֔ה הַ֥/עַל אֵ֖לֶּה אֶנָּחֵֽם", "en": {"kjv": "Among the smooth stones of the stream is thy portion; they, they are thy lot: even to them hast thou poured a drink offering, thou hast offered a meat offering. Should I receive comfort in these?", "web": "Among the smooth stones of the valley is your portion; they, they are your lot; you have even poured a drink offering to them. You have offered an offering. Shall I be appeased for these things?", "bsb": "Your portion is among the smooth stones of the valley; indeed, they are your lot. Even to them you have poured out a drink offering and offered a grain offering. Should I relent because of these?", "asv": "Among the smooth stones of the valley is thy portion; they, they are thy lot; even to them hast thou poured a drink-offering, thou hast offered an oblation. Shall I be appeased for these things?", "ylt": "Among the smooth things of a brook is thy portion, They--they are thy lot, Also to them thou hast poured out an oblation, Thou hast caused a present to ascend, For these things am I comforted?", "dra": "In the parts of the torrent is thy portion, this is thy lot: and thou hast poured out libations to them, thou hast offered sacrifice. Shall I not be angry at these things?", "bbe": "Among the smooth stones of the valley is your heritage; they, even they, are your part: even to them have you made a drink offering and a meal offering. Is it possible for such things to be overlooked by me?", "geneva": "Thy portion is in the smooth stones of the riuer: they, they are thy lot: euen to them hast thou powred a drinke offering: thou hast offered a sacrifice. Should I delite in these?", "wycliffe": "Thi part is in the partis of the stronde, this is thi part; and to tho thou scheddist out moist offryng, thou offridist sacrifice. Whether Y schal not haue indignacioun on these thingis?", "rotherham": "Among the smooth stones of the torrent—valley, is thy portion. They, they, are thy lot; Even to them, hast thou Poured out a drink-offering. Caused to ascend a gift. Over these things, can I cease to grieve?", "darby": "Among the smooth [stones] of the torrent is thy portion; they, they are thy lot: even to them hast thou poured out a drink-offering, thou hast offered an oblation. Shall I be comforted myself as to these things?", "twenty": "", "jps": "Among the smooth stones of the valley is thy portion; they, they are thy lot; even to them hast thou poured a drink-offering, thou hast offered a meal-offering. Should I pacify Myself for these things?", "acv": "Among the smooth stones of the valley is thy portion. They, they are thy lot, even to them thou have poured a drink offering; thou have offered an oblation. Shall I be appeased for these things?", "anderson": "", "haweis": "", "noyes": "With the smooth stones of the valley is thy portion; These, these are thy lot; Here thou pourest out thy drink-offering, And presentest thy meat-offering; Can I see such things, and be at rest?", "webster": "Among the smooth [stones] of the stream [is] thy portion; they, they [are] thy lot: even to them hast thou poured a drink-offering, thou hast offered a meat-offering. Should I receive comfort in these?", "vulgate": "in partibus torrentis pars tua haec est sors tua et ipsis effudisti libamen obtulisti sacrificium numquid super his non indignabor;", "brenton": "That is thy portion, this is thy lot: and to them hast thou poured forth drink-offerings, and to these hast thou offered meat-offerings. Shall I not therefore be angry for these things?"}}, {"v": 7, "ref": "57:7", "o": "עַ֤ל הַר גָּבֹ֨הַּ֙ וְ/נִשָּׂ֔א שַׂ֖מְתְּ מִשְׁכָּבֵ֑/ךְ גַּם שָׁ֥ם עָלִ֖ית לִ/זְבֹּ֥חַ זָֽבַח", "en": {"kjv": "Upon a lofty and high mountain hast thou set thy bed: even thither wentest thou up to offer sacrifice.", "web": "On a high and lofty mountain you have set your bed; there also you went up to offer sacrifice.", "bsb": "On a high and lofty hill you have made your bed, and there you went up to offer sacrifices.", "asv": "Upon a high and lofty mountain hast thou set thy bed; thither also wentest thou up to offer sacrifice.", "ylt": "On a mountain, high and exalted, Thou hast set thy couch, Also thither thou hast gone up to make a sacrifice.", "dra": "Upon a high and lofty mountain thou hast laid thy bed, and hast gone up thither to offer victims.", "bbe": "You have put your bed on a high mountain: there you went up to make your offering.", "geneva": "Thou hast made thy bed vpon a very hie mountaine: thou wentest vp thither, euen thither wentest thou to offer sacrifice.", "wycliffe": "Thou puttidist thi bed on an hiy hil and enhaunsid, and thidur thou stiedist to offre sacrifices;", "rotherham": "On a mountain high and uplifted, hast thou set thy couch,—Even thither, hast thou gone up, to offer sacrifice;", "darby": "Upon a lofty and high mountain hast thou set thy bed: even thither didst thou go up to offer sacrifice.", "twenty": "", "jps": "Upon a high and lofty mountain hast thou set thy bed; thither also wentest thou up to offer sacrifice.", "acv": "Upon a high and lofty mountain thou have set thy bed. Thou also went up there to offer sacrifice.", "anderson": "", "haweis": "", "noyes": "Upon a high and lofty mountain settest thou thy bed; Thither dost thou go up to offer sacrifice;", "webster": "Upon a lofty and high mountain hast thou set thy bed: even thither thou wentest up to offer sacrifice.", "vulgate": "super montem excelsum et sublimem posuisti cubile tuum et illuc ascendisti ut immolares hostias;", "brenton": "On a lofty and high mountain, there is thy bed, and thither thou carriedst up thy meat-offerings:"}}, {"v": 8, "ref": "57:8", "o": "וְ/אַחַ֤ר הַ/דֶּ֨לֶת֙ וְ/הַ/מְּזוּזָ֔ה שַׂ֖מְתְּ זִכְרוֹנֵ֑/ךְ כִּ֣י מֵ/אִתִּ֞/י גִּלִּ֣ית וַֽ/תַּעֲלִ֗י הִרְחַ֤בְתְּ מִשְׁכָּבֵ/ךְ֙ וַ/תִּכְרָת לָ֣/ךְ מֵ/הֶ֔ם אָהַ֥בְתְּ מִשְׁכָּבָ֖/ם יָ֥ד חָזִֽית", "en": {"kjv": "Behind the doors also and the posts hast thou set up thy remembrance: for thou hast discovered thyself to another than me, and art gone up; thou hast enlarged thy bed, and made thee a covenant with them; thou lovedst their bed where thou sawest it.", "web": "Behind the doors and the posts you have set up your memorial: for you have uncovered to someone besides me, and have gone up; you have enlarged your bed, and made you a covenant with them: you loved their bed where you saw it.", "bsb": "Behind the door and doorpost you have set up your memorial. Forsaking Me, you uncovered your bed; you climbed up and opened it wide. And you have made a pact with those whose bed you have loved; you have gazed upon their nakedness.", "asv": "And behind the doors and the posts hast thou set up thy memorial: for thou hast uncovered thyself to another than me, and art gone up; thou hast enlarged thy bed, and made thee a covenant with them: thou lovedst their bed where thou sawest it.", "ylt": "And behind the door, and the post, Thou hast set up thy memorial, For from Me thou hast removed, and goest up, Thou hast enlarged thy couch, And dost covenant for thyself among them, Thou hast loved their couch, the station thou sawest,", "dra": "And behind the door, and behind the post thou hast set up thy remembrance: for thou hast discovered thyself near me, and hast received an adulterer: thou hast enlarged thy bed, and made a covenant with them: thou hast loved their bed with open hand.", "bbe": "And on the back of the doors and on the pillars you have put your sign: for you have been false to me with another; you have made your bed wide, and made an agreement with them; you had a desire for their bed where you saw it", "geneva": "Behinde the doores also and postes hast thou set vp thy remembrance: for thou hast discouered thy selfe to another then me, and wentest vp, and diddest enlarge thy bed, and make a couenant betweene thee and them, and louedst their bed in euery place where thou sawest it.", "wycliffe": "and thou settidist thi memorial bihynde the dore, and bihynde the post. For bisidis me thou vnhilidist, and tokist auouter; thou alargidist thi bed, and madist a boond of pees with hem; thou louedist the bed of hem with openyd hond,", "rotherham": "And behind the door and the post, hast thou set thy symbol, For, with another than me, hast thou uncovered thyself and gone up—Hast widened thy couch, And hast solemnised for thyself a covenant from them, Thou hast loved their couch a sign, hast thou seen;", "darby": "Behind the doors also and the posts hast thou set up thy remembrance: for apart from me, thou hast uncovered thyself, and art gone up; thou hast enlarged thy bed, and hast made agreement with them; thou lovedst their bed, thou sawest their nakedness.", "twenty": "", "jps": "And behind the doors and the posts hast thou set up thy symbol; for thou hast uncovered, and art gone up from Me, thou hast enlarged thy bed, and chosen thee of them whose bed thou lovedst, whose hand thou sawest.", "acv": "And behind the doors and the posts thou have set up thy memorial. For thou have uncovered thyself to another than me, and have gone up. Thou have enlarged thy bed, and made thee a covenant with them. Thou loved their bed where thou saw it.", "anderson": "", "haweis": "", "noyes": "Behind the doors and the posts dost thou place thy memorial; Thou departest from me, and uncoverest, and ascendest, and enlargest thy bed. Thou makest an agreement with them; Thou desirest their bed; Thou choosest a place.", "webster": "Behind the doors also and the posts hast thou set up thy remembrance: for thou hast uncovered [thyself to another] than me, and hast gone up; thou hast enlarged thy bed, and made thee [a covenant] with them; thou lovedst their bed where thou sawest [it].", "vulgate": "et post ostium et retro postem posuisti memoriale tuum quia iuxta me discoperuisti et suscepisti adulterum dilatasti cubile tuum et pepigisti cum eis dilexisti stratum eorum manu aperta;", "brenton": "and behind the posts of thy door thou didst place thy memorials. Didst thou think that if thou shouldest depart from me, thou wouldest gain? thou hast loved those that lay with thee;"}}, {"v": 9, "ref": "57:9", "o": "וַ/תָּשֻׁ֤רִי לַ/מֶּ֨לֶךְ֙ בַּ/שֶּׁ֔מֶן וַ/תַּרְבִּ֖י רִקֻּחָ֑יִ/ךְ וַ/תְּשַׁלְּחִ֤י צִרַ֨יִ/ךְ֙ עַד מֵ֣/רָחֹ֔ק וַ/תַּשְׁפִּ֖ילִי עַד שְׁאֽוֹל", "en": {"kjv": "And thou wentest to the king with ointment, and didst increase thy perfumes, and didst send thy messengers far off, and didst debase thyself even unto hell.", "web": "You went to the king with oil, and increased your perfumes, and sent your ambassadors far off, and debased yourself even to Sheol.", "bsb": "You went to Molech with oil and multiplied your perfumes. You have sent your envoys a great distance; you have descended even to Sheol itself.", "asv": "And thou wentest to the king with oil, and didst increase thy perfumes, and didst send thine ambassadors far off, and didst debase thyself even unto Sheol.", "ylt": "And goest joyfully to the king in ointment, And dost multiply thy perfumes, And sendest thine ambassadors afar off, And humblest thyself unto Sheol.", "dra": "And thou hast adorned thyself for the king with ointment, and hast multiplied thy perfumes. Thou hast sent thy messengers far off, and wast debased even to hell.", "bbe": "And you went to Melech with oil and much perfume, and you sent your representatives far off, and went as low as the underworld.", "geneva": "Thou wentest to the Kings with oyle, and diddest increase thine oyntments and sende thy messengers farre off, and diddest humble thy selfe vnto hell.", "wycliffe": "and ournedist thee with kyngis oynement, and thou multipliedist thi pymentis; thou sentist fer thi messangeris, and thou art maad low `til to hellis.", "rotherham": "And hast gone to the king with oil, And hast multiplied thy perfumes,—And hast sent thy messengers afar, And…lowered thyself as far as hades!", "darby": "And thou wentest to the king with ointment, and didst multiply thy perfumes, and didst send thy messengers afar off, and didst debase thyself unto Sheol.", "twenty": "", "jps": "And thou wentest to the king with ointment, and didst increase thy perfumes, and didst send thine ambassadors far off, even down to the nether-world.", "acv": "And thou went to the king with oil, and increased thy perfumes, and sent thine ambassadors far off, and debased thyself even to Sheol.", "anderson": "", "haweis": "", "noyes": "Thou goest to the king with oil, And takest much precious perfume; Thou sendest thine ambassadors afar, Yea, down to the under-world.", "webster": "And thou wentest to the king with ointment, and didst increase thy perfumes, and didst send thy messengers far off, and didst debase [thyself even] to hell.", "vulgate": "et ornasti te regi unguento et multiplicasti pigmenta tua misisti legatos tuos procul et humiliata es usque ad inferos;", "brenton": "and thou hast multiplied thy whoredom with them, and thou hast increased the number of them that are far from thee, and hast sent ambassadors beyond thy borders, and hast been debased even to hell."}}, {"v": 10, "ref": "57:10", "o": "בְּ/רֹ֤ב דַּרְכֵּ/ךְ֙ יָגַ֔עַתְּ לֹ֥א אָמַ֖רְתְּ נוֹאָ֑שׁ חַיַּ֤ת יָדֵ/ךְ֙ מָצָ֔את עַל כֵּ֖ן לֹ֥א חָלִֽית", "en": {"kjv": "Thou art wearied in the greatness of thy way; yet saidst thou not, There is no hope: thou hast found the life of thine hand; therefore thou wast not grieved.", "web": "You were wearied with the length of your way; yet you didn’t say, ‘It is in vain.’ You found a reviving of your strength; therefore you weren’t faint.", "bsb": "You are wearied by your many journeys, but you did not say, “There is no hope!” You found renewal of your strength; therefore you did not grow weak.", "asv": "Thou wast wearied with the length of thy way; yet saidst thou not, It is in vain: thou didst find a quickening of thy strength; therefore thou wast not faint.", "ylt": "In the greatness of thy way thou hast laboured, Thou hast not said, `It is desperate.' The life of thy hand thou hast found, Therefore thou hast not been sick.", "dra": "Thou hast been wearied in the multitude of thy ways: yet thou saidst not: I will rest: thou has found life of thy hand, therefore thou hast not asked.", "bbe": "You were tired with your long journeys; but you did not say, There is no hope: you got new strength, and so you were not feeble.", "geneva": "Thou weariedst thy selfe in thy manifolde iourneys, yet saydest thou not, There is no hope: thou hast found life by thine hand, therefore thou wast not grieued.", "wycliffe": "Thou trauelidist in the multitude of thi weie, and seidist not, Y schal reste; thou hast founde the weie of thin hond,", "rotherham": "With the length of thy journey, thou wast wearied, Thou didst not say, Hopeless! The reviving of thy power, thou didst find, For this cause, hast thou not become sick.", "darby": "Thou wast wearied by the multitude of thy ways; [but] thou saidst not, It is of no avail. Thou didst find a quickening of thy strength; therefore thou wast not sick [of it].", "twenty": "", "jps": "Thou wast wearied with the length of thy way; yet saidst thou not: 'There is no hope'; thou didst find a renewal of thy strength, therefore thou wast not affected.", "acv": "Thou were wearied with the length of thy way, yet thou did not say, It is in vain. Thou found a quickening of thy strength, therefore thou were not faint.", "anderson": "", "haweis": "", "noyes": "In the length of thy journeys thou hast wearied thyself, But thou sayest not, \"I will desist\"; Thou yet findest life in thy hand, Therefore thou art not discouraged.", "webster": "Thou art wearied in the greatness of thy way; [yet] saidst thou not, There is no hope: thou hast found the life of thy hand; therefore thou wast not grieved.", "vulgate": "in multitudine viae tuae laborasti non dixisti quiescam vitam manus tuae invenisti propterea non rogasti;", "brenton": "Thou has wearied thyself with thy many ways; yet thou saidst not, I will cease to strengthen myself: for thou has done these things; therefore thou has not supplicated me."}}, {"v": 11, "ref": "57:11", "o": "וְ/אֶת מִ֞י דָּאַ֤גְתְּ וַ/תִּֽירְאִי֙ כִּ֣י תְכַזֵּ֔בִי וְ/אוֹתִ/י֙ לֹ֣א זָכַ֔רְתְּ לֹא שַׂ֖מְתְּ עַל לִבֵּ֑/ךְ הֲ/לֹ֨א אֲנִ֤י מַחְשֶׁה֙ וּ/מֵ֣/עֹלָ֔ם וְ/אוֹתִ֖/י לֹ֥א תִירָֽאִי", "en": {"kjv": "And of whom hast thou been afraid or feared, that thou hast lied, and hast not remembered me, nor laid it to thy heart? have not I held my peace even of old, and thou fearest me not?", "web": "“Of whom have you been afraid and in fear, that you lie, and have not remembered me, nor laid it to your heart? Haven’t I held my peace even of long time, and you don’t fear me?", "bsb": "Whom have you dreaded and feared, so that you lied and failed to remember Me or take this to heart? Is it not because I have long been silent that you do not fear Me?", "asv": "And of whom hast thou been afraid and in fear, that thou liest, and hast not remembered me, nor laid it to thy heart? have not I held my peace even of long time, and thou fearest me not?", "ylt": "And of whom hast thou been afraid, and fearest, That thou liest, and Me hast not remembered? Thou hast not laid it to thy heart, Am not I silent, even from of old? And Me thou fearest not?", "dra": "For whom hast thou been solicitous and afraid, that thou hast lied, and hast not been mindful of me, nor thought on me in thy heart? for I am silent, and as one that seeth not, and thou hast forgotten me.", "bbe": "And of whom were you in fear, so that you were false, and did not keep me in mind, or give thought to it? Have I not been quiet, keeping myself secret, and so you were not in fear of me?", "geneva": "And whome diddest thou reuerence or feare, seeing thou hast lyed vnto me, and hast not remembred me, neither set thy minde thereon? is it not because I holde my peace, and that of long time? therefore thou fearest not me.", "wycliffe": "therfor thou preiedist not. For what thing dreddist thou bisy, for thou liedist, and thouytist not on me? And thou thouytist not in thin herte, that Y am stille, and as not seynge; and thou hast foryete me.", "rotherham": "Whom then hadst thou been anxious about and feared that thou shouldest speak falsely, When me, thou rememberedst not, caredst not for me? Did not, I, keep silence even from age-past times, Although me, thou wouldest not fear?", "darby": "And of whom hast thou been afraid or feared, that thou hast lied, and hast not remembered me, nor taken it to heart? Have not I even of long time held my peace, and thou fearest me not?", "twenty": "", "jps": "And of whom hast thou been afraid and in fear, that thou wouldest fail? And as for Me, thou hast not remembered Me, nor laid it to thy heart. Have not I held My peace even of long time? Therefore thou fearest Me not.", "acv": "And of whom have thou been afraid and in fear, that thou lie, and have not remembered me, nor laid it to thy heart? Have I not held my peace even of long time, and thou do not fear me?", "anderson": "", "haweis": "", "noyes": "On account of whom art thou anxious, and of whom art thou afraid, that thou hast proved false, And hast not remembered me, nor laid it to heart? Behold, I have been silent a long time; Therefore thou fearest me not.", "webster": "And of whom hast thou been afraid or feared, that thou hast lied, and hast not remembered me, nor laid [it] to thy heart? have not I held my peace even of old, and thou fearest me not?", "vulgate": "pro quo sollicita timuisti quia mentita es et mei non es recordata neque cogitasti in corde tuo quia ego tacens et quasi non videns et mei oblita es;", "brenton": "Through dread of whom hast thou feared, and lied against me, and has not remembered, nor considered me, nor regarded me, yea, though when I see thee I pass thee by, yet thou has not feared me."}}, {"v": 12, "ref": "57:12", "o": "אֲנִ֥י אַגִּ֖יד צִדְקָתֵ֑/ךְ וְ/אֶֽת מַעֲשַׂ֖יִ/ךְ וְ/לֹ֥א יוֹעִילֽוּ/ךְ", "en": {"kjv": "I will declare thy righteousness, and thy works; for they shall not profit thee.", "web": "I will declare your righteousness; and as for your works, they shall not profit you.", "bsb": "I will expose your righteousness and your works, and they will not profit you.", "asv": "I will declare thy righteousness; and as for thy works, they shall not profit thee.", "ylt": "I declare thy righteousness, and thy works, And they do not profit thee.", "dra": "I will declare thy justice, and thy works shall not profit thee.", "bbe": "I will make clear what your righteousness is like and your works; you will have no profit in them.", "geneva": "I will declare thy righteousnes and thy workes, and they shall not profite thee.", "wycliffe": "Y schal telle thi riytfulnesse, and thi werkis schulen not profite to thee.", "rotherham": "I, will expose thy righteousness,—And thy works—but they will not profit thee!", "darby": "I will declare thy righteousness, and thy works; and they shall not profit thee.", "twenty": "", "jps": "I will declare thy righteousness; thy works also--they shall not profit thee.", "acv": "I will declare thy righteousness. And as for thy works, they shall not profit thee.", "anderson": "", "haweis": "", "noyes": "But now I announce thy deliverance, And thy works do not profit thee.", "webster": "I will declare thy righteousness, and thy works; for they shall not profit thee.", "vulgate": "ego adnuntiabo iustitiam tuam et opera tua non proderunt tibi;", "brenton": "And I will declare thy righteousness, and thy sins, which shall not profit thee."}}, {"v": 13, "ref": "57:13", "o": "בְּ/זַֽעֲקֵ/ךְ֙ יַצִּילֻ֣/ךְ קִבּוּצַ֔יִ/ךְ וְ/אֶת כֻּלָּ֥/ם יִשָּׂא ר֖וּחַ יִקַּח הָ֑בֶל וְ/הַ/חוֹסֶ֥ה בִ/י֙ יִנְחַל אֶ֔רֶץ וְ/יִירַ֖שׁ הַר קָדְשִֽׁ/י", "en": {"kjv": "When thou criest, let thy companies deliver thee; but the wind shall carry them all away; vanity shall take them: but he that putteth his trust in me shall possess the land, and shall inherit my holy mountain;", "web": "When you cry, let those who you have gathered deliver you; but the wind shall take them, a breath shall carry them all away: but he who takes refuge in me shall possess the land, and shall inherit my holy mountain.”", "bsb": "When you cry out, let your companies of idols deliver you! Yet the wind will carry off all of them, a breath will take them away. But he who seeks refuge in Me will inherit the land and possess My holy mountain.”", "asv": "When thou criest, let them that thou hast gathered deliver thee; but the wind shall take them, a breath shall carry them all away: but he that taketh refuge in me shall possess the land, and shall inherit my holy mountain.", "ylt": "When thou criest, let thy gatherings deliver thee, And all of them carry away doth wind, Take away doth vanity, And whoso is trusting in Me inheriteth the land, And doth possess My holy mountain.", "dra": "When thou shalt cry, let thy companies deliver thee, but the wind shall carry them all off, a breeze shall take them away, but he that putteth his trust in me, shall inherit the land, and shall possess my holy mount.", "bbe": "Your false gods will not keep you safe in answer to your cry; but the wind will take them, they will be gone like a breath: but he who puts his hope in me will take the land, and will have my holy mountain as his heritage.", "geneva": "When thou cryest, let them that thou hast gathered together deliuer thee: but the winde shall take them all away: vanitie shall pull them away: but he that trusteth in me, shall inherite the lande, and shall possesse mine holy Mountaine.", "wycliffe": "Whanne thou schalt crie, thi gaderid tresours delyuere thee; and the wynd schal take awei alle tho, a blast schal do awei hem; but he that hath trist on me, schal enherite the lond, and schal haue in possessioun myn hooli hil.", "rotherham": "When thou makest outcry, let thy gathered throngs deliver thee! But all of them, shall A wind, catch up—A breath, take away! Whereas he that seeketh refuge in me, Shall inherit the land, And possess my holy mountain.", "darby": "When thou criest, let them that are gathered by thee deliver thee! But a wind shall carry them all away, a breath shall take them; but he that putteth his trust in me shall inherit the land, and possess my holy mountain.", "twenty": "", "jps": "When thou criest, let them that thou hast gathered deliver thee; but the wind shall carry them all away, a breath shall bear them off; but he that taketh refuge in Me shall possess the land, and shall inherit My holy mountain.", "acv": "When thou cry, let those whom thou have gathered deliver thee. But the wind shall take them; a breath shall carry them all away. But he who takes refuge in me shall possess the land, and shall inherit my holy mountain.", "anderson": "", "haweis": "", "noyes": "When thou criest, let thy host of idols deliver thee! But the wind shall bear them all away; A breath shall take them off; But he that putteth his trust in me Shall possess the land, And shall inherit my holy mountain.", "webster": "When thou criest, let thy companies deliver thee; but the wind shall carry them all away; vanity shall take [them]: but he that putteth his trust in me shall possess the land, and shall inherit my holy mountain;", "vulgate": "cum clamaveris liberent te congregati tui et omnes eos auferet ventus tollet aura qui autem fiduciam habet mei hereditabit terram et possidebit montem sanctum meum;", "brenton": "When thou criest out, let them deliver thee in thine affliction: for all these the wind shall take, and the tempest shall carry them away: but they that cleave to me shall possess the land, and shall inherit my holy mountain."}}, {"v": 14, "ref": "57:14", "o": "וְ/אָמַ֥ר סֹֽלּוּ סֹ֖לּוּ פַּנּוּ דָ֑רֶךְ הָרִ֥ימוּ מִכְשׁ֖וֹל מִ/דֶּ֥רֶךְ עַמִּֽ/י", "en": {"kjv": "And shall say, Cast ye up, cast ye up, prepare the way, take up the stumblingblock out of the way of my people.", "web": "He will say, “Cast up, cast up, prepare the way, take up the stumbling-block out of the way of my people.”", "bsb": "And it will be said, “Build it up, build it up, prepare the way, take every obstacle out of the way of My people.”", "asv": "And he will say, Cast ye up, cast ye up, prepare the way, take up the stumbling-block out of the way of my people.", "ylt": "And he hath said, `Raise up, raise up, prepare a way, Lift a stumbling-block out of the way of My people.'", "dra": "And I will say: Make a way: give free passage, turn out of the path, take away the stumblingblocks out of the way of my people.", "bbe": "And I will say, Make it high, make it high, get ready the way, take the stones out of the way of my people.", "geneva": "And he shall say, Cast vp, cast vp: prepare the way: take vp the stumbling blocks out of the way of my people.", "wycliffe": "And Y schal seie, Make ye weie, yyue ye iurney, bowe ye fro the path, do ye awei hirtyngis fro the weie of my puple.", "rotherham": "And one said—Cast ye up—cast ye up, prepare ye a way,—Lift the stumbling-block out of the way of my people.", "darby": "And it shall be said, Cast up, cast up, prepare the way, take up the stumbling-blocks out of the way of my people.", "twenty": "", "jps": "And He will say: cast ye up, cast ye up, clear the way, take up the stumblingblock out of the way of My people.", "acv": "And he will say, Cast ye up, cast ye up, prepare the way. Take up the stumbling-block out of the way of my people.", "anderson": "", "haweis": "", "noyes": "Men shall say, Cast up, cast up, prepare the road; Remove every obstruction from the way of my people!", "webster": "And shall say, Cast ye up, cast ye up, prepare the way, take up the stumbling-block out of the way of my people.", "vulgate": "et dicam viam facite praebete iter declinate de semita auferte offendicula de via populi mei;", "brenton": "And they shall say, Clear the ways before him, and take up the stumbling-blocks out of the way of my people."}}, {"v": 15, "ref": "57:15", "o": "כִּי֩ כֹ֨ה אָמַ֜ר רָ֣ם וְ/נִשָּׂ֗א שֹׁכֵ֥ן עַד֙ וְ/קָד֣וֹשׁ שְׁמ֔/וֹ מָר֥וֹם וְ/קָד֖וֹשׁ אֶשְׁכּ֑וֹן וְ/אֶת דַּכָּא֙ וּ/שְׁפַל ר֔וּחַ לְ/הַחֲיוֹת֙ ר֣וּחַ שְׁפָלִ֔ים וּֽ/לְ/הַחֲי֖וֹת לֵ֥ב נִדְכָּאִֽים", "en": {"kjv": "For thus saith the high and lofty One that inhabiteth eternity, whose name is Holy; I dwell in the high and holy place, with him also that is of a contrite and humble spirit, to revive the spirit of the humble, and to revive the heart of the contrite ones.", "web": "For thus says the high and lofty One who inhabits eternity, whose name is Holy: “I dwell in the high and holy place, with him also who is of a contrite and humble spirit, to revive the spirit of the humble, and to revive the heart of the contrite.", "bsb": "For thus says the One who is high and lifted up, who inhabits eternity, whose name is Holy: “I dwell in a high and holy place, and with the oppressed and humble in spirit, to restore the spirit of the lowly and revive the heart of the contrite.", "asv": "For thus saith the high and lofty One that inhabiteth eternity, whose name is Holy: I dwell in the high and holy place, with him also that is of a contrite and humble spirit, to revive the spirit of the humble, and to revive the heart of the contrite.", "ylt": "For thus said the high and exalted One, Inhabiting eternity, and holy is His name: `In the high and holy place I dwell, And with the bruised and humble of spirit, To revive the spirit of the humble, And to revive the heart of bruised ones,'", "dra": "For thus saith the High and the Eminent that inhabiteth eternity: and his name is Holy, who dwelleth in the high and holy place, and with a contrite and humble spirit, to revive the spirit of the humble, and to revive the heart of the contrite.", "bbe": "For this is the word of him who is high and lifted up, whose resting-place is eternal, whose name is Holy: my resting-place is in the high and holy place, and with him who is crushed and poor in spirit, to give life to the spirit of the poor, and to make strong the heart of the crushed.", "geneva": "For thus sayth he that is hie and excellent, he that inhabiteth the eternitie, whose Name is the Holy one, I dwell in the high and holy place: with him also that is of a contrite and humble spirite to reuiue the spirite of the humble, and to giue life to them that are of a contrite heart.", "wycliffe": "For the Lord hiy, and enhaunsid, seith these thingis, that dwellith in euerlastyngnesse, and his hooli name in hiy place, and that dwellith in hooli, and with a contrite and meke spirit, that he quykene the spirit of meke men, and quykene the herte of contrit men.", "rotherham": "For, thus, saith he that is high and lifted up—Inhabiting futurity, And, holy, is his name: A high and holy place, will I inhabit, Also with the crushed and lowly in spirit, To revive the spirit of the lowly, and To revive the heart of them who are crushed;—", "darby": "For thus saith the high and lofty One that inhabiteth eternity, and whose name is Holy: I dwell in the high and holy [place], and with him that is of a contrite and humble spirit, to revive the spirit of the humble, and to revive the heart of the contrite ones.", "twenty": "", "jps": "For thus saith the High and Lofty One that inhabiteth eternity, whose name is Holy: I dwell in the high and holy place, with him also that is of a contrite and humble spirit, to revive the spirit of the humble, and to revive the heart of the contrite ones.", "acv": "For thus says the high and lofty One who inhabits eternity, whose name is Holy: I dwell in the high and holy place, also with him who is of a contrite and humble spirit, to revive the spirit of the humble, and to revive the heart of the contrite.", "anderson": "", "haweis": "", "noyes": "For thus saith the high and lofty One That inhabiteth eternity, whose name is Holy: I dwell in the high and holy place; With him also that is of a contrite and humble spirit; To revive the spirit of the humble, And to revive the heart of the contrite ones.", "webster": "For thus saith the high and lofty One that inhabiteth eternity, whose name [is] Holy; I dwell in the high and holy [place], with him also [that is] of a contrite and humble spirit, to revive the spirit of the humble, and to revive the heart of the contrite ones.", "vulgate": "quia haec dicit Excelsus et Sublimis habitans aeternitatem et sanctum nomen eius in excelso et in sancto habitans et cum contrito et humili spiritu ut vivificet spiritum humilium et vivificet cor contritorum;", "brenton": "Thus saith the Most High, who dwells on high for ever, Holy in the holies, is his name, the Most High resting in the holies, and giving patience to the faint-hearted, and giving life to the broken-hearted:"}}, {"v": 16, "ref": "57:16", "o": "כִּ֣י לֹ֤א לְ/עוֹלָם֙ אָרִ֔יב וְ/לֹ֥א לָ/נֶ֖צַח אֶקְּצ֑וֹף כִּי ר֨וּחַ֙ מִ/לְּ/פָנַ֣/י יַֽעֲט֔וֹף וּ/נְשָׁמ֖וֹת אֲנִ֥י עָשִֽׂיתִי", "en": {"kjv": "For I will not contend for ever, neither will I be always wroth: for the spirit should fail before me, and the souls which I have made.", "web": "For I will not contend forever, neither will I be always angry; for the spirit would faint before me, and the souls who I have made.", "bsb": "For I will not accuse you forever, nor will I always be angry; for then the spirit of man would grow weak before Me, with the breath of those I have made.", "asv": "For I will not contend for ever, neither will I be always wroth; for the spirit would faint before me, and the souls that I have made.", "ylt": "For, not to the age do I strive, nor for ever am I wroth, For the spirit from before Me is feeble, And the souls I have made.", "dra": "For I will not contend for ever, neither will I be angry unto the end: because the spirit shall go forth from my face, and breathings I will make.", "bbe": "For I will not give punishment for ever, or be angry without end: for from me breath goes out; and I it was who made the souls.", "geneva": "For I will not contende for euer, neither will I be alwayes wroth, for the spirite should fayle before me: and I haue made the breath.", "wycliffe": "For Y schal not stryue with outen ende, nether Y schal be wrooth `til to the ende; for whi a spirit schal go out fro my face, and Y schal make blastis.", "rotherham": "For not age-abidingly, will I contend, Nor perpetually, will I be wroth,—For, spirit, before me, would faint, Even the breathing souls, which, I, had made.", "darby": "For I will not contend for ever, neither will I be always wroth; for the spirit would fail before me, and the souls [which] I have made.", "twenty": "", "jps": "For I will not contend for ever, neither will I be always wroth; for the spirit that enwrappeth itself is from Me, and the souls which I have made.", "acv": "For I will not contend forever, nor will I always be angry, for the spirit would faint before me, and the souls that I have made.", "anderson": "", "haweis": "", "noyes": "For I will not contend forever, Nor will I be always angry; For life would fail before me, And the souls which I created.", "webster": "For I will not contend for ever, neither will I be always wroth: for the spirit would fail before me, and the souls [which] I have made.", "vulgate": "non enim in sempiternum litigabo neque usque ad finem irascar quia spiritus a facie mea egredietur et flatus ego faciam;", "brenton": "I will not take vengeance on you for ever, neither will I be always angry with you: for my Spirit shall go forth from me, and I have created all breath."}}, {"v": 17, "ref": "57:17", "o": "בַּ/עֲוֺ֥ן בִּצְע֛/וֹ קָצַ֥פְתִּי וְ/אַכֵּ֖/הוּ הַסְתֵּ֣ר וְ/אֶקְצֹ֑ף וַ/יֵּ֥לֶךְ שׁוֹבָ֖ב בְּ/דֶ֥רֶךְ לִבּֽ/וֹ", "en": {"kjv": "For the iniquity of his covetousness was I wroth, and smote him: I hid me, and was wroth, and he went on frowardly in the way of his heart.", "web": "For the iniquity of his covetousness was I angry, and struck him; I hid myself and was angry; and he went on backsliding in the way of his heart.", "bsb": "I was enraged by his sinful greed, so I struck him and hid My face in anger; yet he kept turning back to the desires of his heart.", "asv": "For the iniquity of his covetousness was I wroth, and smote him; I hid my face and was wroth; and he went on backsliding in the way of his heart.", "ylt": "For the iniquity of his dishonest gain, I have been wroth, and I smite him, Hiding--and am wroth, And he goeth on turning back in the way of his heart.", "dra": "For the iniquity of his covetousness I was angry, and I struck him: I hid my face from thee, and was angry: and he went away wandering in his own heart.", "bbe": "I was quickly angry with his evil ways, and sent punishment on him, veiling my face in wrath: and he went on, turning his heart from me.", "geneva": "For his wicked couetousnesse I am angry with him, and haue smitten him: I hid mee and was angry, yet he went away, and turned after the way of his owne heart.", "wycliffe": "Y was wrooth for the wickidnesse of his aueryce, and Y smoot hym. Y hidde my face fro thee, and Y hadde indignacioun; and he yede with out stidfast dwellyng, in the weie of his herte.", "rotherham": "Because of his iniquitous gain, was I wroth—and smote him Hiding myself that I might be wroth,—But he went on turning aside in the way of his own heart.", "darby": "For the iniquity of his covetousness was I wroth, and smote him; I hid me, and was wroth, and he went on backslidingly in the way of his heart.", "twenty": "", "jps": "For the iniquity of his covetousness was I wroth and smote him, I hid Me and was wroth; and he went on frowardly in the way of his heart.", "acv": "For the iniquity of his covetousness I was angry, and smote him. I hid my face and was angry, and he went on backsliding in the way of his heart.", "anderson": "", "haweis": "", "noyes": "For the guilt of his covetousness I was angry; I smote him, I hid myself, and was angry; But yet he went on perversely in the way of his heart.", "webster": "For the iniquity of his covetousness I was wroth, and smote him: I hid me, and was wroth, and he went on frowardly in the way of his heart.", "vulgate": "propter iniquitatem avaritiae eius iratus sum et percussi eum abscondi et indignatus sum et abiit vagus in via cordis sui;", "brenton": "On account of sin for a little while I grieved him, and smote him, and turned away my face from him; and he was grieved, and he went on sorrowful in his ways."}}, {"v": 18, "ref": "57:18", "o": "דְּרָכָ֥י/ו רָאִ֖יתִי וְ/אֶרְפָּאֵ֑/הוּ וְ/אַנְחֵ֕/הוּ וַ/אֲשַׁלֵּ֧ם נִֽחֻמִ֛ים ל֖/וֹ וְ/לַ/אֲבֵלָֽי/ו", "en": {"kjv": "I have seen his ways, and will heal him: I will lead him also, and restore comforts unto him and to his mourners.", "web": "I have seen his ways, and will heal him: I will lead him also, and restore comforts to him and to his mourners.", "bsb": "I have seen his ways, but I will heal him; I will guide him and restore comfort to him and his mourners,", "asv": "I have seen his ways, and will heal him: I will lead him also, and restore comforts unto him and to his mourners.", "ylt": "His ways I have seen, and I heal him, yea, I lead him, And recompense comforts to him and to his mourning ones.", "dra": "I saw his ways, and I healed him, and brought him back, and restored comforts to him, and to them that mourn for him.", "bbe": "I have seen his ways, and I will make him well: I will give him rest, comforting him and his people who are sad.", "geneva": "I haue seene his wayes, and wil heale him: I wil leade him also, and restore comfort vnto him, and to those that lament him.", "wycliffe": "Y siy hise weies, and Y helide hym, and Y brouyte hym ayen; and Y yaf coumfortyngis to hym, and to the moreneris of hym.", "rotherham": "His ways, have I beheld, That I might heal him,—And guide him, And restore consolations to him and to his mourners:", "darby": "I have seen his ways, and will heal him; and I will lead him, and will restore comforts unto him and to those of his that mourn.", "twenty": "", "jps": "I have seen his ways, and will heal him; I will lead him also, and requite with comforts him and his mourners.", "acv": "I have seen his ways, and will heal him. I will lead him also, and restore comforts to him and to his mourners.", "anderson": "", "haweis": "", "noyes": "I have seen his ways, yet will I heal him; I will guide him, and I will restore comfort To him and to his mourners;", "webster": "I have seen his ways, and will heal him: I will lead him also, and restore comforts to him and to his mourners.", "vulgate": "vias eius vidi et dimisi eum et reduxi eum et reddidi consolationes ipsi et lugentibus eius;", "brenton": "I have seen his ways, and healed him, and comforted him, and given him true comfort;"}}, {"v": 19, "ref": "57:19", "o": "בּוֹרֵ֖א נוב נִ֣יב שְׂפָתָ֑יִם שָׁל֨וֹם שָׁל֜וֹם לָ/רָח֧וֹק וְ/לַ/קָּר֛וֹב אָמַ֥ר יְהוָ֖ה וּ/רְפָאתִֽי/ו", "en": {"kjv": "I create the fruit of the lips; Peace, peace to him that is far off, and to him that is near, saith the Lord; and I will heal him.", "web": "I create the fruit of the lips: Peace, peace, to him who is far off and to him who is near,” says Yahweh; “and I will heal them.”", "bsb": "bringing praise to their lips. Peace, peace to those far and near,” says the LORD, “and I will heal them.”", "asv": "I create the fruit of the lips: Peace, peace, to him that is far off and to him that is near, saith Jehovah; and I will heal him.", "ylt": "Producing the fruit of the lips, `Peace, peace,' to the far off, and to the near, And I have healed him, said Jehovah.", "dra": "I created the fruit of the lips, peace, peace to him that is far off, and to him that is near, said the Lord, and I healed him.", "bbe": "I will give the fruit of the lips: Peace, peace, to him who is near and to him who is far off, says the Lord; and I will make him well.", "geneva": "I create the fruite of the lips, to be peace: peace vnto them that are farre off, and to them that are neere, sayth the Lord: for I will heale him.", "wycliffe": "Y made the fruyt of lippis pees, pees to hym that is fer, and to hym that is niy, seide the Lord; and Y heelide hym.", "rotherham": "Creating the fruit of the lips—Prosperity! Prosperity! For him that is far off and for him that is near saith Yahweh, So should I heal him.", "darby": "I create the fruit of the lips: peace, peace to him [that is] afar off, and to him [that is] nigh, saith Jehovah; and I will heal him.", "twenty": "", "jps": "Peace, peace, to him that is far off and to him that is near, saith HaShem that createth the fruit of the lips; and I will heal him.", "acv": "I create the fruit of the lips. Peace, peace, to him who is far off and to him who is near, says Jehovah, and I will heal him.", "anderson": "", "haweis": "", "noyes": "I create the fruit of the lips. Peace, peace to him that is far off, and to him that is nigh, Saith Jehovah; I will heal him.", "webster": "I create the fruit of the lips; Peace, peace to [him that is] far off, and to [him that is] near, saith the LORD; and I will heal him.", "vulgate": "creavi fructum labiorum pacem pacem ei qui longe est et qui prope dixit Dominus et sanavi eum;", "brenton": "peace upon peace to them that are far off, and to them that are nigh: and the Lord has said, I will heal them."}}, {"v": 20, "ref": "57:20", "o": "וְ/הָ/רְשָׁעִ֖ים כַּ/יָּ֣ם נִגְרָ֑שׁ כִּ֤י הַשְׁקֵט֙ לֹ֣א יוּכָ֔ל וַ/יִּגְרְשׁ֥וּ מֵימָ֖י/ו רֶ֥פֶשׁ וָ/טִֽיט", "en": {"kjv": "But the wicked are like the troubled sea, when it cannot rest, whose waters cast up mire and dirt.", "web": "But the wicked are like the troubled sea; for it can’t rest, and its waters cast up mire and dirt.", "bsb": "But the wicked are like the storm-tossed sea, for it cannot be still, and its waves churn up mire and muck.", "asv": "But the wicked are like the troubled sea; for it cannot rest, and its waters cast up mire and dirt.", "ylt": "And the wicked are as the driven out sea, For to rest it is not able, And its waters cast out filth and mire.", "dra": "But the wicked are like the raging sea, which cannot rest, and the waves thereof cast up dirt and mire.", "bbe": "But the evil-doers are like the troubled sea, for which there is no rest, and its waters send up earth and waste.", "geneva": "But the wicked are like the raging sea, that can not rest, whose waters cast vp myre and dirt.", "wycliffe": "But wickid men ben as the buyling see, that may not reste; and the wawis therof fleten ayen in to defoulyng, and fen.", "rotherham": "But, the lawless, are like the sea when tossed,—For, rest, it cannot! But its waters toss out mire and dirt.", "darby": "But the wicked are like the troubled sea, which cannot rest, and whose waters cast up mire and dirt.", "twenty": "", "jps": "But the wicked are like the troubled sea; for it cannot rest, and its waters cast up mire and dirt.", "acv": "But the wicked are like the troubled sea, for it cannot rest, and its waters cast up mire and dirt.", "anderson": "", "haweis": "", "noyes": "But the wicked is like the troubled sea, Which cannot rest, Whose waters cast up mire and dirt.", "webster": "But the wicked [are] like the troubled sea, when it cannot rest, whose waters cast up mire and dirt.", "vulgate": "impii autem quasi mare fervens quod quiescere non potest et redundant fluctus eius in conculcationem et lutum;", "brenton": "But the unrighteous shall be tossed as troubled waves, and shall not be able to rest."}}, {"v": 21, "ref": "57:21", "o": "אֵ֣ין שָׁל֔וֹם אָמַ֥ר אֱלֹהַ֖/י לָ/רְשָׁעִֽים", "en": {"kjv": "There is no peace, saith my God, to the wicked.", "web": "“There is no peace”, says my God, “for the wicked.”", "bsb": "“There is no peace,” says my God, “for the wicked.”", "asv": "There is no peace, saith my God, to the wicked.", "ylt": "There is no peace, said my God, to the wicked!", "dra": "There is no peace to the wicked, saith the Lord God.", "bbe": "There is no peace, says my God, for the evil-doers.", "geneva": "There is no peace, sayth my God, to the wicked.", "wycliffe": "The Lord God seide, Pees is not to wickid men.", "rotherham": "No well-being, saith my God, to the lawless!", "darby": "There is no peace, saith myGod, to the wicked.", "twenty": "", "jps": "There is no peace, saith my G-d concerning the wicked.", "acv": "There is no peace, says my God, to the wicked.", "anderson": "", "haweis": "", "noyes": "There is no peace, saith my God, for the wicked.", "webster": "[There is] no peace, saith my God, to the wicked.", "vulgate": "non est pax dixit Deus meus impiis;", "brenton": "There is no joy to the ungodly, said God."}}]}, {"c": 58, "verses": [{"v": 1, "ref": "58:1", "o": "קְרָ֤א בְ/גָרוֹן֙ אַל תַּחְשֹׂ֔ךְ כַּ/שּׁוֹפָ֖ר הָרֵ֣ם קוֹלֶ֑/ךָ וְ/הַגֵּ֤ד לְ/עַמִּ/י֙ פִּשְׁעָ֔/ם וּ/לְ/בֵ֥ית יַעֲקֹ֖ב חַטֹּאתָֽ/ם", "en": {"kjv": "Cry aloud, spare not, lift up thy voice like a trumpet, and shew my people their transgression, and the house of Jacob their sins.", "web": "“Cry aloud, don’t spare, lift up your voice like a trumpet, and declare to my people their disobedience, and to the house of Jacob their sins.", "bsb": "“Cry aloud, do not hold back! Raise your voice like a ram’s horn. Declare to My people their transgression and to the house of Jacob their sins.", "asv": "Cry aloud, spare not, lift up thy voice like a trumpet, and declare unto my people their transgression, and to the house of Jacob their sins.", "ylt": "Call with the throat, restrain not, As a trumpet lift up thy voice, And declare to My people their transgression, And to the house of Jacob their sins;", "dra": "Cry, cease not, lift up thy voice like a trumpet, and shew my people their wicked doings, and the house of Jacob their sins.", "bbe": "Make a loud cry, do not be quiet, let your voice be sounding like a horn, and make clear to my people their evil doings, and to the family of Jacob their sins.", "geneva": "Crye aloude, spare not: lift vp thy voyce like a trumpet, and shewe my people their transgression, and to the house of Iaakob, their sinnes.", "wycliffe": "Crye thou, ceesse thou not; as a trumpe enhaunse thi vois, and schewe thou to my puple her grete trespassis, and to the hous of Jacob her synnes.", "rotherham": "Cry aloud, do not spare, Like a horn, lift high thy voice,—And declare To my people, their transgression, and To the house of Jacob their sins.", "darby": "Cry aloud, spare not, lift up thy voice like a trumpet, and declare unto my people their transgression, and to the house of Jacob their sins.", "twenty": "", "jps": "Cry aloud, spare not, lift up thy voice like a horn, and declare unto My people their transgression, and to the house of Jacob their sins.", "acv": "Cry aloud, spare not. Lift up thy voice like a trumpet, and declare to my people their transgression, and to the house of Jacob their sins.", "anderson": "", "haweis": "", "noyes": "Cry aloud, spare not, Lift up thy voice like a trumpet, And show my people their transgression, And the house of Jacob their sins!", "webster": "Cry aloud, spare not, lift up thy voice like a trumpet, and show my people their transgression, and the house of Jacob their sins.", "vulgate": "clama ne cesses quasi tuba exalta vocem tuam et adnuntia populo meo scelera eorum et domui Iacob peccata eorum;", "brenton": "Cry aloud, and spare not; lift up thy voice as with a trumpet, and declare to my people their sins, and to the house of Jacob their iniquities."}}, {"v": 2, "ref": "58:2", "o": "וְ/אוֹתִ֗/י י֥וֹם יוֹם֙ יִדְרֹשׁ֔וּ/ן וְ/דַ֥עַת דְּרָכַ֖/י יֶחְפָּצ֑וּ/ן כְּ/ג֞וֹי אֲשֶׁר צְדָקָ֣ה עָשָׂ֗ה וּ/מִשְׁפַּ֤ט אֱלֹהָי/ו֙ לֹ֣א עָזָ֔ב יִשְׁאָל֨וּ/נִי֙ מִשְׁפְּטֵי צֶ֔דֶק קִרְבַ֥ת אֱלֹהִ֖ים יֶחְפָּצֽוּ/ן", "en": {"kjv": "Yet they seek me daily, and delight to know my ways, as a nation that did righteousness, and forsook not the ordinance of their God: they ask of me the ordinances of justice; they take delight in approaching to God.", "web": "Yet they seek me daily, and delight to know my ways: as a nation that did righteousness, and didn’t forsake the ordinance of their God, they ask of me righteous judgments; they delight to draw near to God.", "bsb": "For day after day they seek Me and delight to know My ways, like a nation that does what is right and does not forsake the justice of their God. They ask Me for righteous judgments; they delight in the nearness of God.”", "asv": "Yet they seek me daily, and delight to know my ways: as a nation that did righteousness, and forsook not the ordinance of their God, they ask of me righteous judgments; they delight to draw near unto God.", "ylt": "Seeing--Me day by day they seek, And the knowledge of My ways they desire, As a nation that righteousness hath done, And the judgment of its God hath not forsaken, They ask of me judgments of righteousness, The drawing near of God they desire:", "dra": "For they seek me from day to day, and desire to know my ways, as a nation that hath done justice, and hath not forsaken the judgment of their God: they ask of me the judgments of justice: they are willing to approach to God.", "bbe": "Though they make prayer to me every day, and take pleasure in the knowledge of my ways: like a nation which has done righteousness, and has not given up the rules of their God, they make requests to me for the right orders, it is their delight to come near to God.", "geneva": "Yet they seeke me dayly, and will knowe my wayes, euen as a nation that did righteously, and had not forsaken the statutes of their God: they aske of me the ordinances of iustice: they wil drawe neere vnto God, saying,", "wycliffe": "For thei seken me fro dai in to dai, and thei wolen knowe my weies; as a folk, that hath do riytfulnesse, and that hath not forsake the doom of her God; thei preien me domes of riytfulnesse, and wolen neiy to God.", "rotherham": "Yet, me—day by day, do they seek, And in the knowledge of my ways, they delight,—Like a nation that had done righteousness, And the justice of their God, had not forsaken They ask of me the just regulations, In approaching God, they delight.", "darby": "Yet they seek me daily, and delight to know my ways, as a nation that doeth righteousness, and hath not forsaken the ordinance of theirGod; they ask of me the ordinances of righteousness, they take delight in approaching toGod:", "twenty": "", "jps": "Yet they seek Me daily, and delight to know My ways; as a nation that did righteousness, and forsook not the ordinance of their G-d, they ask of Me righteous ordinances, they delight to draw near unto G-d.", "acv": "Yet they seek me daily, and delight to know my ways. As a nation that did righteousness, and forsook not the ordinance of their God, they ask of me righteous judgments; they delight to draw near to God.", "anderson": "", "haweis": "", "noyes": "Yet they seek me daily, And desire to know my ways, As a nation that hath done righteousness, And hath not forsaken the ordinances of their God; They inquire of me concerning the judgments which bring salvation; They long for the coming of God.", "webster": "Yet they seek me daily, and delight to know my ways, as a nation that did righteousness, and forsook not the ordinance of their God: they ask of me the ordinances of justice; they take delight in approaching to God.", "vulgate": "me etenim de die in diem quaerunt et scire vias meas volunt quasi gens quae iustitiam fecerit et quae iudicium Dei sui non reliquerit rogant me iudicia iustitiae adpropinquare Deo volunt;", "brenton": "They seek me day by day, and desire to know my ways, as a people that had done righteousness, and had not forsaken the judgment of their God: they now ask of me righteous judgment, and desire to draw nigh to God,"}}, {"v": 3, "ref": "58:3", "o": "לָ֤/מָּה צַּ֨מְנוּ֙ וְ/לֹ֣א רָאִ֔יתָ עִנִּ֥ינוּ נַפְשֵׁ֖/נוּ וְ/לֹ֣א תֵדָ֑ע הֵ֣ן בְּ/י֤וֹם צֹֽמְ/כֶם֙ תִּמְצְאוּ חֵ֔פֶץ וְ/כָל עַצְּבֵי/כֶ֖ם תִּנְגֹּֽשׂוּ", "en": {"kjv": "Wherefore have we fasted, say they, and thou seest not? wherefore have we afflicted our soul, and thou takest no knowledge? Behold, in the day of your fast ye find pleasure, and exact all your labours.", "web": "‘Why have we fasted,’ say they, ‘and you don’t see? Why have we afflicted our soul, and you take no knowledge?’ “Behold, in the day of your fast you find pleasure, and exact all your labors.", "bsb": "“Why have we fasted, and You have not seen? Why have we humbled ourselves, and You have not noticed?” “Behold, on the day of your fast, you do as you please, and you oppress all your workers.", "asv": "Wherefore have we fasted, say they, and thou seest not? wherefore have we afflicted our soul, and thou takest no knowledge? Behold, in the day of your fast ye find your own pleasure, and exact all your labors.", "ylt": "`Why have we fasted, and Thou hast not seen? We have afflicted our soul, and Thou knowest not.' Lo, in the day of your fast ye find pleasure, And all your labours ye exact.", "dra": "Why have we fasted, and thou hast not regarded: have we humbled our souls, and thou hast not taken notice? Behold in the day of your fast your own will is found, and you exact of all your debtors.", "bbe": "They say, Why have we kept ourselves from food, and you do not see it? why have we kept ourselves from pleasure, and you take no note of it? If, in the days when you keep from food, you take the chance to do your business, and get in your debts;", "geneva": "Wherefore haue we fasted, and thou seest it not? we haue punished our selues, and thou regardest it not. Beholde, in the day of your fast you will seeke your will, and require all your dettes.", "wycliffe": "Whi fastiden we, and thou biheldist not; we mekiden oure soulis, and thou knewist not? Lo! youre wille is foundun in the dai of youre fastyng, and ye axen alle youre dettouris.", "rotherham": "Wherefore have we Fasted and thou hast not seen? Humbled our soul, and thou wouldst take no note? Lo! in the day of your fast, ye take pleasure, But all your toilers, ye drive on!", "darby": "— Wherefore have we fasted, and thou seest not; have afflicted our soul, and thou takest no knowledge? Behold, in the day of your fast ye find what pleaseth [you], and exact all your labours.", "twenty": "", "jps": "'Wherefore have we fasted, and Thou seest not? Wherefore have we afflicted our soul, and Thou takest no knowledge?'-- Behold, in the day of your fast ye pursue your business, and exact all your labours.", "acv": "Why have we fasted, they say, and thou see not? We have afflicted our soul, and thou take no knowledge. Behold, in the day of your fast ye find pleasure, and exact from all your laborers.", "anderson": "", "haweis": "", "noyes": "\"Wherefore do we fast, and thou seest not? Wherefore do we afflict our souls, and thou dost not regard it?\" Behold, in the day of your fasts ye pursue your pleasure, And exact all your labors.", "webster": "Why have we fasted, [say they], and thou seest not? [why] have we afflicted our soul, and thou takest no knowledge? Behold, in the day of your fast ye find pleasure, and exact all your labors.", "vulgate": "quare ieiunavimus et non aspexisti humiliavimus animam nostram et nescisti ecce in die ieiunii vestri invenitur voluntas et omnes debitores vestros repetitis;", "brenton": "saying, Why have we fasted, and thou regardest not? why have we afflicted our souls, and thou didst not know it? Nay, in the days of your fasts ye find your pleasures, and all them that are under your power ye wound."}}, {"v": 4, "ref": "58:4", "o": "הֵ֣ן לְ/רִ֤יב וּ/מַצָּה֙ תָּצ֔וּמוּ וּ/לְ/הַכּ֖וֹת בְּ/אֶגְרֹ֣ף רֶ֑שַׁע לֹא תָצ֣וּמוּ כַ/יּ֔וֹם לְ/הַשְׁמִ֥יעַ בַּ/מָּר֖וֹם קוֹלְ/כֶֽם", "en": {"kjv": "Behold, ye fast for strife and debate, and to smite with the fist of wickedness: ye shall not fast as ye do this day, to make your voice to be heard on high.", "web": "Behold, you fast for strife and contention, and to strike with the fist of wickedness: you don’t fast this day so as to make your voice to be heard on high.", "bsb": "You fast with contention and strife to strike viciously with your fist. You cannot fast as you do today and have your voice be heard on high.", "asv": "Behold, ye fast for strife and contention, and to smite with the fist of wickedness: ye fast not this day so as to make your voice to be heard on high.", "ylt": "Lo, for strife and debate ye fast, And to smite with the fist of wickedness, Ye fast not as to -day, To sound in the high place your voice.", "dra": "Behold you fast for debates and strife, and strike with the fist wickedly. Do not fast as you have done until this day, to make your cry to be heard on high.", "bbe": "If keeping from food makes you quickly angry, ready for fighting and giving blows with evil hands; your holy days are not such as to make your voice come to my ears on high.", "geneva": "Beholde, ye fast to strife and debate, and to smite with the fist of wickednesse: ye shall not fast as ye doe to day, to make your voyce to be heard aboue.", "wycliffe": "Lo! ye fasten to chidyngis and stryuyngis, and smyten with the fist wickidli. Nyl ye fast, as `til to this dai, that youre cry be herd an hiy.", "rotherham": "Lo! for strife and contention, ye fast, And to smite with the fist of lawlessness,—Ye shall not fast as to-day, To cause to be heard on high your voice!", "darby": "Behold, ye have fasted for strife and debate, and to smite with the fist of wickedness; ye do not at present fast, to cause your voice to be heard on high.", "twenty": "", "jps": "Behold, ye fast for strife and contention, and to smite with the fist of wickedness; ye fast not this day so as to make your voice to be heard on high.", "acv": "Behold, ye fast for strife and contention, and to smite with the fist of wickedness. Ye do not fast this day so as to make your voice to be heard on high.", "anderson": "", "haweis": "", "noyes": "Behold, ye fast in strife and contention, And smiting with the fist of wickedness. Ye do not fast now So that your voice shall be heard on high.", "webster": "Behold, ye fast for strife and debate, and to smite with the fist of wickedness: ye shall not fast as [ye do this] day, to make your voice to be heard on high.", "vulgate": "ecce ad lites et contentiones ieiunatis et percutitis pugno impie nolite ieiunare sicut usque ad hanc diem ut audiatur in excelso clamor vester;", "brenton": "If ye fast for quarrels and strifes, and smite the lowly with your fists, wherefore do ye fast to me as ye do this day, so that your voice may be heard in crying?"}}, {"v": 5, "ref": "58:5", "o": "הֲ/כָ/זֶ֗ה יִֽהְיֶה֙ צ֣וֹם אֶבְחָרֵ֔/הוּ י֛וֹם עַנּ֥וֹת אָדָ֖ם נַפְשׁ֑/וֹ הֲ/לָ/כֹ֨ף כְּ/אַגְמֹ֜ן רֹאשׁ֗/וֹ וְ/שַׂ֤ק וָ/אֵ֨פֶר֙ יַצִּ֔יעַ הֲ/לָ/זֶה֙ תִּקְרָא צ֔וֹם וְ/י֥וֹם רָצ֖וֹן לַ/יהוָֽה", "en": {"kjv": "Is it such a fast that I have chosen? a day for a man to afflict his soul? is it to bow down his head as a bulrush, and to spread sackcloth and ashes under him? wilt thou call this a fast, and an acceptable day to the Lord?", "web": "Is such the fast that I have chosen? the day for a man to afflict his soul? Is it to bow down his head as a rush, and to spread sackcloth and ashes under him? Will you call this a fast, and an acceptable day to Yahweh?", "bsb": "Is this the fast I have chosen: a day for a man to deny himself, to bow his head like a reed, and to spread out sackcloth and ashes? Will you call this a fast and a day acceptable to the LORD?", "asv": "Is such the fast that I have chosen? the day for a man to afflict his soul? Is it to bow down his head as a rush, and to spread sackcloth and ashes under him? wilt thou call this a fast, and an acceptable day to Jehovah?", "ylt": "Like this is the fast that I choose? The day of a man's afflicting his soul? To bow as a reed his head, And sackcloth and ashes spread out? This dost thou call a fast, And a desirable day--to Jehovah?", "dra": "Is this such a fast as I have chosen: for a man to afflict his soul for a day? is this it, to wind his head about like a circle, and to spread sackcloth and ashes? wilt thou call this a fast, and a day acceptable to the Lord?", "bbe": "Have I given orders for such a day as this? a day for keeping yourselves from pleasure? is it only a question of the bent head, of putting on haircloth, and being seated in the dust? is this what seems to you a holy day, well-pleasing to the Lord?", "geneva": "Is it such a fast that I haue chosen, that a man should afflict his soule for a day, and to bowe downe his head, as a bull rush, and to lie downe in sackecloth and ashes? wilt thou call this a fasting, or an acceptable day to the Lord?", "wycliffe": "Whether sich is the fastyng which Y chees, a man to turmente his soule bi dai? whether to bynde his heed as a sercle, and to make redi a sak and aische? Whethir thou schalt clepe this a fastyng, and a dai acceptable to the Lord?", "rotherham": "Like this, shall the fast be that I choose, A day for the son of earth to humble his soul? Is it to bow down as a rush his head, And sackcloth and ashes, to spread out? Is it, this, thou wilt call a fast, Or a day of acceptance with Yahweh?", "darby": "Is such the fast that I have chosen, a day for a man to afflict his soul, — that he should bow down his head as a bulrush, and spread sackcloth and ashes [under him]? Wilt thou call this a fast, and a day acceptable to Jehovah?", "twenty": "", "jps": "Is such the fast that I have chosen? the day for a man to afflict his soul? Is it to bow down his head as a bulrush, and to spread sackcloth and ashes under him? Wilt thou call this a fast, and an acceptable day to HaShem?", "acv": "Is such the fast that I have chosen, the day for a man to afflict his soul? Is it to bow down his head as a rush, and to spread sackcloth and ashes under him? Will thou call this a fast, and an acceptable day to Jehovah?", "anderson": "", "haweis": "", "noyes": "Is this the fast that I approve, A day for a man to afflict his soul? Is it that he should bow down his head like a bulrush, And lie down in sackcloth and ashes? Wilt thou call this a fast, And a day acceptable to Jehovah?", "webster": "Is it such a fast that I have chosen? a day for a man to afflict his soul? [is it] to bow down his head as a bulrush, and to spread sackcloth and ashes [under him]? wilt thou call this a fast, and an acceptable day to the LORD?", "vulgate": "numquid tale est ieiunium quod elegi per diem adfligere hominem animam suam numquid contorquere quasi circulum caput suum et saccum et cinerem sternere numquid istud vocabis ieiunium et diem acceptabilem Domino;", "brenton": "I have not chosen this fast, nor such a day for a man to afflict his soul; neither though thou shouldest bend down thy neck as a ring, and spread under thee sackcloth and ashes, neither thus shall ye call a fast acceptable."}}, {"v": 6, "ref": "58:6", "o": "הֲ/ל֣וֹא זֶה֮ צ֣וֹם אֶבְחָרֵ/הוּ֒ פַּתֵּ֨חַ֙ חַרְצֻבּ֣וֹת רֶ֔שַׁע הַתֵּ֖ר אֲגֻדּ֣וֹת מוֹטָ֑ה וְ/שַׁלַּ֤ח רְצוּצִים֙ חָפְשִׁ֔ים וְ/כָל מוֹטָ֖ה תְּנַתֵּֽקוּ", "en": {"kjv": "Is not this the fast that I have chosen? to loose the bands of wickedness, to undo the heavy burdens, and to let the oppressed go free, and that ye break every yoke?", "web": "“Isn’t this the fast that I have chosen: to release the bonds of wickedness, to undo the bands of the yoke, and to let the oppressed go free, and that you break every yoke?", "bsb": "Isn’t this the fast that I have chosen: to break the chains of wickedness, to untie the cords of the yoke, to set the oppressed free and tear off every yoke?", "asv": "Is not this the fast that I have chosen: to loose the bonds of wickedness, to undo the bands of the yoke, and to let the oppressed go free, and that ye break every yoke?", "ylt": "Is not this the fast that I chose--To loose the bands of wickedness, To shake off the burdens of the yoke, And to send out the oppressed free, And every yoke ye draw off?", "dra": "Is not this rather the fast that I have chosen? loose the bands of wickedness, undo the bundles that oppress, let them that are broken go free, and break asunder every burden.", "bbe": "Is not this the holy day for which I have given orders: to let loose those who have wrongly been made prisoners, to undo the bands of the yoke, and to let the crushed go free, and every yoke be broken?", "geneva": "Is not this the fasting, that I haue chosen, to loose the bandes of wickednes, to take off the heauie burdens, and to let the oppressed goe free, and that ye breake euery yoke?", "wycliffe": "Whether not this is more the fastyng, which Y chees? Vnbynde thou the byndingis togidere of vnpitee, releesse thou birthuns pressynge doun; delyuere thou hem free, that ben brokun, and breke thou ech birthun.", "rotherham": "Is not, this, the fast that I must ever choose—To unbind the tight cords of lawlessness, To unloose the bands of the yoke,—and To let the crushed go free, and That every yoke, ye tear off?", "darby": "Is not this the fast which I have chosen: to loose the bands of wickedness, to undo the thongs of the yoke, and to send forth free the crushed, and that ye break every yoke?", "twenty": "", "jps": "Is not this the fast that I have chosen? to loose the fetters of wickedness, to undo the bands of the yoke, and to let the oppressed go free, and that ye break every yoke?", "acv": "Is not this the fast that I have chosen: to loose the bonds of wickedness, to undo the bands of the yoke, and to let the oppressed go free, and that ye break every yoke?", "anderson": "", "haweis": "", "noyes": "Is not this the fast that I approve,—To loose the bands of wickedness, To undo the heavy burdens, To let the oppressed go free, And to break in pieces every yoke?", "webster": "[Is] not this the fast that I have chosen? to loose the bands of wickedness, to undo the heavy burdens, and to let the oppressed go free, and that ye break every yoke?", "vulgate": "nonne hoc est magis ieiunium quod elegi dissolve conligationes impietatis solve fasciculos deprimentes dimitte eos qui confracti sunt liberos et omne onus disrumpe;", "brenton": "I have not chosen such a fast, saith the Lord; but do thou loose every burden of iniquity, do thou untie the knots of hard bargains, set the bruised free, and cancel every unjust account."}}, {"v": 7, "ref": "58:7", "o": "הֲ/ל֨וֹא פָרֹ֤ס לָֽ/רָעֵב֙ לַחְמֶ֔/ךָ וַ/עֲנִיִּ֥ים מְרוּדִ֖ים תָּ֣בִיא בָ֑יִת כִּֽי תִרְאֶ֤ה עָרֹם֙ וְ/כִסִּית֔/וֹ וּ/מִ/בְּשָׂרְ/ךָ֖ לֹ֥א תִתְעַלָּֽם", "en": {"kjv": "Is it not to deal thy bread to the hungry, and that thou bring the poor that are cast out to thy house? when thou seest the naked, that thou cover him; and that thou hide not thyself from thine own flesh?", "web": "Isn’t it to distribute your bread to the hungry, and that you bring the poor who are cast out to your house? When you see the naked, that you cover him; and that you not hide yourself from your own flesh?", "bsb": "Isn’t it to share your bread with the hungry, to bring the poor and homeless into your home, to clothe the naked when you see him, and not to turn away from your own flesh and blood?", "asv": "Is it not to deal thy bread to the hungry, and that thou bring the poor that are cast out to thy house? when thou seest the naked, that thou cover him; and that thou hide not thyself from thine own flesh?", "ylt": "Is it not to deal to the hungry thy bread, And the mourning poor bring home, That thou seest the naked and cover him, And from thine own flesh hide not thyself?", "dra": "Deal thy bread to the hungry, and bring the needy and the harbourless into thy house: when thou shalt see one naked, cover him, and despise not thy own flesh.", "bbe": "Is it not to give your bread to those in need, and to let the poor who have no resting-place come into your house? to put a robe on the unclothed one when you see him, and not to keep your eyes shut for fear of seeing his flesh?", "geneva": "Is it not to deale thy bread to the hungry, and that thou bring the poore that wander, vnto thine house? when thou seest the naked, that thou couer him, and hide not thy selfe from thine owne flesh?", "wycliffe": "Breke thi breed to an hungri man, and brynge in to thin hous nedi men and herborles; whanne thou seest a nakid man, hile thou hym, and dispise not thi fleisch.", "rotherham": "Is it not to break unto the hungry, thy bread, And the thrust-out oppressed, that thou bring into a home,—When thou seest one naked, that thou cover him, And from thine own flesh, shalt not hide thyself?", "darby": "Is it not to deal thy bread to the hungry, and that thou bring to thy house the needy wanderers; when thou seest the naked, that thou cover him; and that thou hide not thyself from thine own flesh?", "twenty": "", "jps": "Is it not to deal thy bread to the hungry, and that thou bring the poor that are cast out to thy house? when thou seest the naked, that thou cover him, and that thou hide not thyself from thine own flesh?", "acv": "Is it not to deal thy bread to a hungry man, and that thou bring the poor who are cast out to thy house, when thou see a naked man, that thou cover him, and that thou not hide thyself from thine own flesh?", "anderson": "", "haweis": "", "noyes": "Is it not to break thy bread to the hungry, And to bring the poor, that are cast out, to thy house? When thou seest the naked, that thou clothe him, And that thou hide not thyself from thine own flesh?", "webster": "[Is it] not to deal thy bread to the hungry, and that thou shouldst bring the poor that are cast out to thy house? when thou seest the naked, that thou shouldst cover him; and that thou shouldst not hide thyself from thy own flesh?", "vulgate": "frange esurienti panem tuum et egenos vagosque induc in domum tuam cum videris nudum operi eum et carnem tuam ne despexeris;", "brenton": "Break thy bread to the hungry, and lead the unsheltered poor to thy house: if thou seest one naked, clothe him, and thou shalt not disregard the relations of thine own seed."}}, {"v": 8, "ref": "58:8", "o": "אָ֣ז יִבָּקַ֤ע כַּ/שַּׁ֨חַר֙ אוֹרֶ֔/ךָ וַ/אֲרֻכָתְ/ךָ֖ מְהֵרָ֣ה תִצְמָ֑ח וְ/הָלַ֤ךְ לְ/פָנֶ֨י/ךָ֙ צִדְקֶ֔/ךָ כְּב֥וֹד יְהוָ֖ה יַאַסְפֶֽ/ךָ", "en": {"kjv": "Then shall thy light break forth as the morning, and thine health shall spring forth speedily: and thy righteousness shall go before thee; the glory of the Lord shall be thy rereward.", "web": "Then your light shall break out as the morning, and your healing shall spring out speedily; and your righteousness shall go before you; Yahweh’s glory shall be your rear guard.", "bsb": "Then your light will break forth like the dawn, and your healing will come quickly. Your righteousness will go before you, and the glory of the LORD will be your rear guard.", "asv": "Then shall thy light break forth as the morning, and thy healing shall spring forth speedily; and thy righteousness shall go before thee; the glory of Jehovah shall be thy rearward.", "ylt": "Then broken up as the dawn is thy light, And thy health in haste springeth up, Gone before thee hath thy righteousness, The honour of Jehovah doth gather thee.", "dra": "Then shall thy light break forth as the morning, and thy health shall speedily arise, and thy justice shall go before thy face, and the glory of the Lord shall gather thee up.", "bbe": "Then will light be shining on you like the morning, and your wounds will quickly be well: and your righteousness will go before you, and the glory of the Lord will come after you.", "geneva": "Then shall thy light breake foorth as the morning, and thine health shall grow speedily: thy righteousnes shall goe before thee, and the glorie of the Lord shall embrace thee.", "wycliffe": "Thanne thi liyt schal breke out as the morewtid, and thin helthe schal rise ful soone; and thi riytfulnesse schal go bifore thi face, and the glorie of the Lord schal gadere thee.", "rotherham": "Then, shall break forth, as the dawn, thy light, And thy new flesh shall speedily grow,—Then shall go before thee, thy righteousness, the glory of Yahweh shall bring up thy rear:", "darby": "Then shall thy light break forth as the dawn, and thy health shall spring forth speedily; and thy righteousness shall go before thee, the glory of Jehovah shall be thy rearguard.", "twenty": "", "jps": "Then shall thy light break forth as the morning, and thy healing shall spring forth speedily; and thy righteousness shall go before thee, the glory of HaShem shall be thy rearward.", "acv": "Then thy light shall break forth as the morning, and thy healing shall spring forth speedily. And thy righteousness shall go before thee. The glory of Jehovah shall be thy rearward.", "anderson": "", "haweis": "", "noyes": "Then shall thy light break forth like the morning, And thy health shall spring forth speedily; Thy salvation shall go before thee, And the glory of Jehovah shall bring up thy rear.", "webster": "Then shall thy light break forth as the morning, and thy health shall spring forth speedily: and thy righteousness shall go before thee; the glory of the LORD shall be thy rear-ward.", "vulgate": "tunc erumpet quasi mane lumen tuum et sanitas tua citius orietur et anteibit faciem tuam iustitia tua et gloria Domini colliget te;", "brenton": "Then shall thy light break forth as the morning, and thy health shall speedily spring forth: and thy righteousness shall go before thee, and the glory of God shall compass thee."}}, {"v": 9, "ref": "58:9", "o": "אָ֤ז תִּקְרָא֙ וַ/יהוָ֣ה יַעֲנֶ֔ה תְּשַׁוַּ֖ע וְ/יֹאמַ֣ר הִנֵּ֑/נִי אִם תָּסִ֤יר מִ/תּֽוֹכְ/ךָ֙ מוֹטָ֔ה שְׁלַ֥ח אֶצְבַּ֖ע וְ/דַבֶּר אָֽוֶן", "en": {"kjv": "Then shalt thou call, and the Lord shall answer; thou shalt cry, and he shall say, Here I am. If thou take away from the midst of thee the yoke, the putting forth of the finger, and speaking vanity;", "web": "Then you shall call, and Yahweh will answer; you shall cry, and he will say, ‘Here I am.’ “If you take away from your midst the yoke, the putting out of the finger, and speaking wickedly;", "bsb": "Then you will call, and the LORD will answer; you will cry out, and He will say, ‘Here I am.’ If you remove the yoke from your midst, the pointing of the finger and malicious talk,", "asv": "Then shalt thou call, and Jehovah will answer; thou shalt cry, and he will say, Here I am. If thou take away from the midst of thee the yoke, the putting forth of the finger, and speaking wickedly;", "ylt": "Then thou callest, and Jehovah answereth, Thou criest, and He saith, `Behold Me.' If thou turn aside from thy midst the yoke, The sending forth of the finger, And the speaking of vanity,", "dra": "Then shalt thou call, and the Lord shall hear: thou shalt cry, and he shall say, Here I am. If thou wilt take away the chain out of the midst of thee, and cease to stretch out the finger, and to speak that which profiteth not.", "bbe": "Then at the sound of your voice, the Lord will give an answer; at your cry he will say, Here am I. If you take away from among you the yoke, the putting out of the finger of shame, and the evil word;", "geneva": "Then shalt thou call, and the Lord shall answere: thou shalt cry and hee shall say, Here I am: if thou take away from the mids of thee the yoke, the putting foorth of the finger, and wicked speaking:", "wycliffe": "Thanne thou schalt clepe to help, and the Lord schal here; thou schalt crie, and he schal seie, Lo! Y am present, for Y am merciful, thi Lord God. If thou takist awei a chayne fro the myddis of thee, and ceessist to holde forth the fyngur, and to speke that profitith not;", "rotherham": "Then, shalt thou Call, and Yahweh, will answer, Cry out, and he will say, Behold me! If thou remove, out of thy midst the yoke, The pointing of the finger, and The speaking of iniquity;", "darby": "Then shalt thou call, and Jehovah will answer; thou shalt cry, and he will say, Here I am. If thou take away from the midst of thee the yoke, the putting forth of the finger and the unjust speech,", "twenty": "", "jps": "Then shalt thou call, and HaShem will answer; thou shalt cry, and He will say: 'Here I am.' If thou take away from the midst of thee the yoke, the putting forth of the finger, and speaking wickedness;", "acv": "Then thou shall call, and Jehovah will answer, thou shall cry, and he will say, Here I am. If thou take the yoke away from the midst of thee, the putting forth of the finger, and speaking wickedly,", "anderson": "", "haweis": "", "noyes": "Then shalt thou call, and Jehovah will answer; Thou shalt cry, and he shall say, Lo, here I am! If thou remove from the midst of thee the yoke, The pointing of the finger, and the injurious speech.", "webster": "Then shalt thou call, and the LORD will answer; thou shalt cry, and he will say, Here I [am]. If thou shalt take away from the midst of thee the yoke, the putting forth of the finger, and speaking vanity;", "vulgate": "tunc invocabis et Dominus exaudiet clamabis et dicet ecce adsum si abstuleris de medio tui catenam et desieris digitum extendere et loqui quod non prodest;", "brenton": "Then shalt thou cry, and God shall hearken to thee; while thou art yet speaking he will say, Behold, I am here. If thou remove from thee the band, and the stretching forth of the hands, and murmuring speech;"}}, {"v": 10, "ref": "58:10", "o": "וְ/תָפֵ֤ק לָֽ/רָעֵב֙ נַפְשֶׁ֔/ךָ וְ/נֶ֥פֶשׁ נַעֲנָ֖ה תַּשְׂבִּ֑יעַ וְ/זָרַ֤ח בַּ/חֹ֨שֶׁךְ֙ אוֹרֶ֔/ךָ וַ/אֲפֵלָתְ/ךָ֖ כַּֽ/צָּהֳרָֽיִם", "en": {"kjv": "And if thou draw out thy soul to the hungry, and satisfy the afflicted soul; then shall thy light rise in obscurity, and thy darkness be as the noonday:", "web": "and if you draw out your soul to the hungry, and satisfy the afflicted soul: then your light shall rise in darkness, and your obscurity be as the noonday;", "bsb": "and if you give yourself to the hungry and satisfy the afflicted soul, then your light will go forth in the darkness, and your night will be like noonday.", "asv": "and if thou draw out thy soul to the hungry, and satisfy the afflicted soul: then shall thy light rise in darkness, and thine obscurity be as the noonday;", "ylt": "And dost bring out to the hungry thy soul, And the afflicted soul dost satisfy, Then risen in the darkness hath thy light, And thy thick darkness is as noon.", "dra": "When thou shalt pour out thy soul to the hungry, and shalt satisfy the afflicted soul, then shall thy light rise up in darkness, and thy darkness shall be as the noonday.", "bbe": "And if you give your bread to those in need of it, so that the troubled one may have his desire; then you will have light in the dark, and your night will be as the full light of the sun:", "geneva": "If thou powre out thy soule to the hungrie, and refresh the troubled soule: then shall thy light spring out in the darkenes, and thy darkenes shalbe as the noone day.", "wycliffe": "whanne thou schedist out thi soule to an hungri man, and fillist a soule, `that is turmentid, thi liyt schal rise in derknessis, and thi derknessis schulen be as myddai.", "rotherham": "And shalt let thine own soul go out to the hungry, And the soul of the oppressed, thou shalt satisfy, Then shall break forth in darkness thy light, And thy thick darkness, become as the splendour of noon;", "darby": "and thou proffer thy soul to the hungry, and satisfy the afflicted soul: then shall thy light rise in the darkness, and thine obscurity be as midday;", "twenty": "", "jps": "And if thou draw out thy soul to the hungry, and satisfy the afflicted soul; then shall thy light rise in darkness, and thy gloom be as the noon-day;", "acv": "and if thou draw out thy soul to a hungry man, and satisfy an afflicted soul, then thy light shall rise in darkness, and thine obscurity be as the noonday.", "anderson": "", "haweis": "", "noyes": "If thou bring forth thy bread to the hungry, And satisfy the afflicted soul, Then in obscurity shall light arise to thee; Yea, thy darkness shall become as noonday;", "webster": "And [if] thou shalt draw out thy soul to the hungry, and satisfy the afflicted soul; then shall thy light rise in obscurity, and thy darkness [be] as the noon day:", "vulgate": "cum effuderis esurienti animam tuam et animam adflictam repleveris orietur in tenebris lux tua et tenebrae tuae erunt sicut meridies;", "brenton": "and if thou give bread to the hungry from thy heart, and satisfy the afflicted soul; then shall thy light spring up in darkness, and thy darkness shall be as noon-day:"}}, {"v": 11, "ref": "58:11", "o": "וְ/נָחֲ/ךָ֣ יְהוָה֮ תָּמִיד֒ וְ/הִשְׂבִּ֤יעַ בְּ/צַחְצָחוֹת֙ נַפְשֶׁ֔/ךָ וְ/עַצְמֹתֶ֖י/ךָ יַחֲלִ֑יץ וְ/הָיִ֨יתָ֙ כְּ/גַ֣ן רָוֶ֔ה וּ/כְ/מוֹצָ֣א מַ֔יִם אֲשֶׁ֥ר לֹא יְכַזְּב֖וּ מֵימָֽי/ו", "en": {"kjv": "And the Lord shall guide thee continually, and satisfy thy soul in drought, and make fat thy bones: and thou shalt be like a watered garden, and like a spring of water, whose waters fail not.", "web": "and Yahweh will guide you continually, and satisfy your soul in dry places, and make strong your bones; and you shall be like a watered garden, and like a spring of water, whose waters don’t fail.", "bsb": "The LORD will always guide you; He will satisfy you in a sun-scorched land and strengthen your frame. You will be like a well-watered garden, like a spring whose waters never fail.", "asv": "and Jehovah will guide thee continually, and satisfy thy soul in dry places, and make strong thy bones; and thou shalt be like a watered garden, and like a spring of water, whose waters fail not.", "ylt": "And Jehovah doth lead thee continually, And hath satisfied in drought thy soul, And thy bones He armeth, And thou hast been as a watered garden, And as an outlet of waters, whose waters lie not.", "dra": "And the Lord will give thee rest continually, and will fill thy soul with brightness, and deliver thy bones, and thou shalt be like a watered garden, and like a fountain of water whose waters shall not fail.", "bbe": "And the Lord will be your guide at all times; in dry places he will give you water in full measure, and will make strong your bones; and you will be like a watered garden, and like an ever-flowing spring.", "geneva": "And the Lord shall guide thee continually, and satisfie thy soule in drought, and make fat thy bones: and thou shalt be like a watred garden, and like a spring of water, whose waters faile not.", "wycliffe": "And the Lord thi God schal yyue euere reste to thee, and schal fille thi soule with schynyngis, and schal delyuere thi boonys; and thou schalt be as a watri gardyn, and as a welle of watris, whose waters schulen not faile.", "rotherham": "Then will Yahweh guide thee continually, And will satisfy, [even] in scorched regions thine own soul, Yea thy very bones, will he invigorate,—So shall thou become like a garden well—watered, And like a spring of water whose waters do not deceive;", "darby": "and Jehovah will guide thee continually, and satisfy thy soul in drought, and strengthen thy bones; and thou shalt be like a watered garden, and like a water-spring, whose waters deceive not.", "twenty": "", "jps": "And HaShem will guide thee continually, and satisfy thy soul in drought, and make strong thy bones; and thou shalt be like a watered garden, and like a spring of water, whose waters fail not.", "acv": "And Jehovah will guide thee continually, and satisfy thy soul in dry places, and make strong thy bones. And thou shall be like a watered garden, and like a spring of water whose waters fail not.", "anderson": "", "haweis": "", "noyes": "Jehovah shall lead thee continually, And satisfy thee in the time of drought, And strengthen thy bones; Thou shalt be like a watered garden, and a spring of water, Whose waters never fail.", "webster": "And the LORD will guide thee continually, and satisfy thy soul in drouth, and make fat thy bones: and thou shalt be like a watered garden, and like a spring of water, whose waters fail not.", "vulgate": "et requiem tibi dabit Dominus semper et implebit splendoribus animam tuam et ossa tua liberabit et eris quasi hortus inriguus et sicut fons aquarum cuius non deficient aquae;", "brenton": "and thy God shall be with thee continually, and thou shalt be satisfied according as thy soul desires; and thy bones shall be made fat, and shall be as a well-watered garden, and as a fountain from which the water has not failed."}}, {"v": 12, "ref": "58:12", "o": "וּ/בָנ֤וּ מִמְּ/ךָ֙ חָרְב֣וֹת עוֹלָ֔ם מוֹסְדֵ֥י דוֹר וָ/ד֖וֹר תְּקוֹמֵ֑ם וְ/קֹרָ֤א לְ/ךָ֙ גֹּדֵ֣ר פֶּ֔רֶץ מְשֹׁבֵ֥ב נְתִיב֖וֹת לָ/שָֽׁבֶת", "en": {"kjv": "And they that shall be of thee shall build the old waste places: thou shalt raise up the foundations of many generations; and thou shalt be called, The repairer of the breach, The restorer of paths to dwell in.", "web": "Those who shall be of you shall build the old waste places; you shall raise up the foundations of many generations; and you shall be called The repairer of the breach, The restorer of paths to dwell in.", "bsb": "Your people will rebuild the ancient ruins; you will restore the age-old foundations; you will be called Repairer of the Breach, Restorer of the Streets of Dwelling.", "asv": "And they that shall be of thee shall build the old waste places; thou shalt raise up the foundations of many generations; and thou shalt be called The repairer of the breach, The restorer of paths to dwell in.", "ylt": "And they have built out of thee the wastes of old, The foundations of many generations thou raisest up, And one calleth thee, `Repairer of the breach, Restorer of paths to rest in.'", "dra": "And the places that have been desolate for ages shall be built in thee: thou shalt raise up the foundation of generation and generation: and thou shalt be called the repairer of the fences, turning the paths into rest.", "bbe": "And your sons will be building again the old waste places: you will make strong the bases of old generations: and you will be named, He who puts up the broken walls, and, He who makes ready the ways for use.", "geneva": "And they shalbe of thee, that shall builde the olde waste places: thou shalt rayse vp the foundations for many generations, and thou shalt be called the repairer of the breach and the restorer of the pathes to dwell in.", "wycliffe": "And the forsakun thingis of worldis schulen be bildid in thee, and thou schalt reise the foundementis of generacioun and generacioun; and thou schalt be clepid a bildere of heggis, turnynge awei the pathis of wickidnessis.", "rotherham": "And they who come of thee shall build the wastes of age-past times, And as for the foundations of generation after generation, thou shalt rear them up,—So shalt thou be called—A Repairer of broken walls, A Restorer of paths leading home.", "darby": "And they [that come] of thee shall build the old waste places: thou shalt raise up the foundations [that have remained] from generation to generation; and thou shalt be called, Repairer of the breaches, restorer of frequented paths.", "twenty": "", "jps": "And they that shall be of thee shall build the old waste places, thou shalt raise up the foundations of many generations; and thou shalt be called The repairer of the breach, the restorer of paths to dwell in.", "acv": "And those who shall be of thee shall build the old waste places. Thou shall raise up the foundations of many generations, and thou shall be called The repairer of the breach, The restorer of paths to dwell in.", "anderson": "", "haweis": "", "noyes": "Thy people shall build the ancient desolations, The ruins of many generations shall they restore; Thou shalt be called the repairer of the breach, The restorer of ways for inhabitants.", "webster": "And [they that shall be] of thee shall build the old waste places: thou shalt raise up the foundations of many generations; and thou shalt be called, The repairer of the breach, The restorer of paths to dwell in.", "vulgate": "et aedificabuntur in te deserta saeculorum fundamenta generationis et generationis suscitabis et vocaberis aedificator sepium avertens semitas in quietem;", "brenton": "And thy old waste desert places shall be built up, and thy foundations shall last through all generations; and thou shalt be called a repairer of breaches, and thou shalt cause thy paths between to be in peace."}}, {"v": 13, "ref": "58:13", "o": "אִם תָּשִׁ֤יב מִ/שַּׁבָּת֙ רַגְלֶ֔/ךָ עֲשׂ֥וֹת חֲפָצֶ֖י/ךָ בְּ/י֣וֹם קָדְשִׁ֑/י וְ/קָרָ֨אתָ לַ/שַּׁבָּ֜ת עֹ֗נֶג לִ/קְד֤וֹשׁ יְהוָה֙ מְכֻבָּ֔ד וְ/כִבַּדְתּ/וֹ֙ מֵ/עֲשׂ֣וֹת דְּרָכֶ֔י/ךָ מִ/מְּצ֥וֹא חֶפְצְ/ךָ֖ וְ/דַבֵּ֥ר דָּבָֽר", "en": {"kjv": "If thou turn away thy foot from the sabbath, from doing thy pleasure on my holy day; and call the sabbath a delight, the holy of the Lord, honourable; and shalt honour him, not doing thine own ways, nor finding thine own pleasure, nor speaking thine own words:", "web": "“If you turn away your foot from the Sabbath, from doing your pleasure on my holy day; and call the Sabbath a delight, and the holy of Yahweh honorable; and shall honor it, not doing your own ways, nor finding your own pleasure, nor speaking your own words:", "bsb": "If you turn your foot from breaking the Sabbath, from doing as you please on My holy day, if you call the Sabbath a delight, and the LORD’s holy day honorable, if you honor it by not going your own way or seeking your own pleasure or speaking idle words,", "asv": "If thou turn away thy foot from the sabbath, from doing thy pleasure on my holy day; and call the sabbath a delight, and the holy of Jehovah honorable; and shalt honor it, not doing thine own ways, nor finding thine own pleasure, nor speaking thine own words:", "ylt": "If thou dost turn from the sabbath thy foot, Doing thine own pleasure on My holy day, And hast cried to the sabbath, `A delight,' To the holy of Jehovah, `Honoured,' And hast honoured it, without doing thine own ways, Without finding thine own pleasure, And speaking a word.", "dra": "If thou turn away thy foot from the sabbath, from doing thy own will in my holy day, and call the sabbath delightful, and the holy of the Lord glorious, and glorify him, while thou dost not thy own ways, and thy own will is not found, to speak a word:", "bbe": "If you keep the Sabbath with care, not doing your business on my holy day; and if the Sabbath seems to you a delight, and the new moon of the Lord a thing to be honoured; and if you give respect to him by not doing your business, or going after your pleasure, or saying unholy words;", "geneva": "If thou turne away thy foote from the Sabbath, from doing thy will on mine holy day, and call the Sabbath a delite, to consecrate it, as glorious to the Lord, and shalt honour him, not doing thine owne wayes, nor seeking thine owne will, nor speaking a vaine word,", "wycliffe": "If thou turnest awei thi foot fro the sabat, to do thi wille in myn hooli dai, and clepist the sabat delicat, and hooli, the gloriouse of the Lord, and glorifiest him, while thou doist not thi weies, and thi wille is not foundun, that thou speke a word;", "rotherham": "If thou turn back. From the sabbath thy foot, From doing thine own pleasure on my holy day,—And shall call—The sabbath, An exquisite delight, The holy day of Yahweh, A day to be honoured, And so shall honour it rather—Than do thine own ways, Than take thine own pleasure or Than speak thine own word,", "darby": "If thou turn back thy foot from the sabbath, [from] doing thy pleasure on my holy day, and call the sabbath a delight, the holy [day] of Jehovah, honourable; and thou honour him, not doing thine own ways, nor finding thine own pleasure, nor speaking [idle] words;", "twenty": "", "jps": "If thou turn away thy foot because of the sabbath, from pursuing thy business on My holy day; and call the sabbath a delight, and the holy of HaShem honourable; and shalt honour it, not doing thy wonted ways, nor pursuing thy business, nor speaking thereof;", "acv": "If thou turn away thy foot from the sabbath, from doing thy pleasure on my holy day, and call the sabbath a delight, and the holy of Jehovah honorable, and shall honor it, not doing thine own ways, nor finding thine own pleasure, nor speaking thine own words:", "anderson": "", "haweis": "", "noyes": "If thou restrain thy foot from the sabbath, From doing thy pleasure on my holy day, If thou shalt call the sabbath a delight, The holy day of Jehovah honorable, And shalt honor it by refraining from thy work, From doing thy pleasure, and speaking vain words,", "webster": "If thou shalt turn away thy foot from the sabbath, [from] doing thy pleasure on my holy day; and call the sabbath a delight, the holy of the LORD, honorable; and shalt honor him, not doing thy own ways, nor finding thy own pleasure, nor speaking [thy own] words:", "vulgate": "si averteris a sabbato pedem tuum facere voluntatem tuam in die sancto meo et vocaveris sabbatum delicatum et sanctum Domini gloriosum et glorificaveris eum dum non facis vias tuas et non invenitur voluntas tua ut loquaris sermonem;", "brenton": "If thou turn away thy foot from the sabbath, so as not to do thy pleasure on the holy days, and shalt call the sabbaths delightful, holy to God; if thou shalt not lift up thy foot to work, nor speak a word in anger out of thy mouth,"}}, {"v": 14, "ref": "58:14", "o": "אָ֗ז תִּתְעַנַּג֙ עַל יְהוָ֔ה וְ/הִרְכַּבְתִּ֖י/ךָ עַל בָּ֣מֳותֵי אָ֑רֶץ וְ/הַאֲכַלְתִּ֗י/ךָ נַחֲלַת֙ יַעֲקֹ֣ב אָבִ֔י/ךָ כִּ֛י פִּ֥י יְהוָ֖ה דִּבֵּֽר", "en": {"kjv": "Then shalt thou delight thyself in the Lord; and I will cause thee to ride upon the high places of the earth, and feed thee with the heritage of Jacob thy father: for the mouth of the Lord hath spoken it.", "web": "then you shall delight yourself in Yahweh; and I will make you to ride on the high places of the earth; and I will feed you with the heritage of Jacob your father:” for the mouth of Yahweh has spoken it.", "bsb": "then you will delight yourself in the LORD, and I will make you ride on the heights of the land and feed you with the heritage of your father Jacob.” For the mouth of the LORD has spoken.", "asv": "then shalt thou delight thyself in Jehovah; and I will make thee to ride upon the high places of the earth; and I will feed thee with the heritage of Jacob thy father: for the mouth of Jehovah hath spoken it.", "ylt": "Then dost thou delight thyself on Jehovah, And I have caused thee to ride on high places of earth, And have caused thee to eat the inheritance of Jacob thy father, For the mouth of Jehovah hath spoken!", "dra": "Then shalt thou be delighted in the Lord, and I will lift thee up above the high places of the earth, and will feed thee with the inheritance of Jacob thy father. For the mouth of the Lord hath spoken it.", "bbe": "Then the Lord will be your delight; and I will put you on the high places of the earth; and I will give you the heritage of Jacob your father: for the mouth of the Lord has said it.", "geneva": "Then shalt thou delite in the Lord, and I wil cause thee to mount vpon the hie places of the earth, and feede thee with the heritage of Iaakob thy father: for the mouth of ye Lord hath spoken it.", "wycliffe": "thanne thou schalt delite on the Lord, and Y schal reise thee on the hiynesse of erthe, and Y schal fede thee with the eritage of Jacob, thi fadir; for whi the mouth of the Lord spak.", "rotherham": "Then, shalt thou rest thine own exquisite delight upon Yahweh, …And I will cause thee to ride over the high places of the land,—And will feed thee with the inheritance of Jacob thy father, For the mouth of Yahweh, hath spoken.", "darby": "then shalt thou delight thyself in Jehovah, and I will cause thee to ride on the high places of the earth, and feed thee with the heritage of Jacob thy father: for the mouth of Jehovah hath spoken.", "twenty": "", "jps": "Then shalt thou delight thyself in HaShem, and I will make thee to ride upon the high places of the earth, and I will feed thee with the heritage of Jacob thy father; for the mouth of HaShem hath spoken it.", "acv": "then thou shall delight thyself in Jehovah, and I will make thee to ride upon the high places of the earth, and I will feed thee with the heritage of Jacob thy father. For the mouth of Jehovah has spoken it.", "anderson": "", "haweis": "", "noyes": "Then shalt thou delight thyself in Jehovah. And I will cause thee to ride upon the high places of the earth, And cause thee to enjoy the inheritance of Jacob, thy father; For the mouth of Jehovah hath spoken it.", "webster": "Then shalt thou delight thyself in the LORD; and I will cause thee to ride upon the high places of the earth, and feed thee with the heritage of Jacob thy father: for the mouth of the LORD hath spoken [it].", "vulgate": "tunc delectaberis super Domino et sustollam te super altitudines terrae et cibabo te hereditate Iacob patris tui os enim Domini locutum est;", "brenton": "then shalt thou trust on the Lord; and he shall bring thee up to the good places of the land, and feed thee with the heritage of Jacob thy father: for the mouth of the Lord has spoken this."}}]}, {"c": 59, "verses": [{"v": 1, "ref": "59:1", "o": "הֵ֛ן לֹֽא קָצְרָ֥ה יַד יְהוָ֖ה מֵֽ/הוֹשִׁ֑יעַ וְ/לֹא כָבְדָ֥ה אָזְנ֖/וֹ מִ/שְּׁמֽוֹעַ", "en": {"kjv": "Behold, the Lord’s hand is not shortened, that it cannot save; neither his ear heavy, that it cannot hear:", "web": "Behold, Yahweh’s hand is not shortened, that it can’t save; neither his ear heavy, that it can’t hear:", "bsb": "Surely the arm of the LORD is not too short to save, nor His ear too dull to hear.", "asv": "Behold, Jehovah’s hand is not shortened, that it cannot save; neither his ear heavy, that it cannot hear:", "ylt": "Lo, the hand of Jehovah Hath not been shortened from saving, Nor heavy his ear from hearing.", "dra": "Behold the hand of the Lord is not shortened that it cannot save, neither is his ear heavy that it cannot hear.", "bbe": "Truly, the Lord's hand has not become short, so that he is unable to give salvation; and his ear is not shut from hearing:", "geneva": "Beholde, the Lordes hande is not shortened, that it can not saue: neither is his eare heauie, that it cannot heare.", "wycliffe": "Lo! the hoond of the Lord is not abreggid, that he mai not saue, nether his eere is maad hard, that he here not;", "rotherham": "Lo! the hand of Yahweh is not too short to save,—Neither is his ear too heavy to hear.", "darby": "Behold, Jehovah's hand is not shortened that it cannot save, neither his ear heavy that it cannot hear;", "twenty": "", "jps": "Behold, HaShem'S hand is not shortened, that it cannot save, neither His ear heavy, that it cannot hear;", "acv": "Behold, Jehovah's hand is not shortened, that it cannot save, nor his ear heavy, that it cannot hear.", "anderson": "", "haweis": "", "noyes": "Behold, Jehovah’s hand is not shortened, that it cannot save, Nor is his ear heavy, that it cannot hear;", "webster": "Behold, the LORD'S hand is not shortened, that it cannot save; neither his ear heavy, that it cannot hear:", "vulgate": "ecce non est adbreviata manus Domini ut salvare nequeat neque adgravata est auris eius ut non exaudiat;", "brenton": "Has the hand of the Lord no power to save? or has he made his ear heavy, so that he should not hear?"}}, {"v": 2, "ref": "59:2", "o": "כִּ֤י אִם עֲוֺנֹֽתֵי/כֶם֙ הָי֣וּ מַבְדִּלִ֔ים בֵּינֵ/כֶ֕ם לְ/בֵ֖ין אֱלֹֽהֵי/כֶ֑ם וְ/חַטֹּֽאותֵי/כֶ֗ם הִסְתִּ֧ירוּ פָנִ֛ים מִ/כֶּ֖ם מִ/שְּׁמֽוֹעַ", "en": {"kjv": "But your iniquities have separated between you and your God, and your sins have hid his face from you, that he will not hear.", "web": "but your iniquities have separated between you and your God, and your sins have hidden his face from you, so that he will not hear.", "bsb": "But your iniquities have built barriers between you and your God, and your sins have hidden His face from you, so that He does not hear.", "asv": "but your iniquities have separated between you and your God, and your sins have hid his face from you, so that he will not hear.", "ylt": "But your iniquities have been separating Between you and your God, And your sins have hidden The Presence from you--from hearing.", "dra": "But your iniquities have divided between you and your God, and your sins have hid his face from you that he should not hear.", "bbe": "But your sins have come between you and your God, and by your evil doings his face has been veiled from you, so that he will give you no answer.", "geneva": "But your iniquities haue separated betweene you and your God, and your sinnes haue hidde his face from you, that he will not heare.", "wycliffe": "but youre wickidnessis han departid bitwixe you and youre God, and youre synnes han hid his face fro you, that he schulde not here.", "rotherham": "But, your iniquities, have become separators betwixt you and your God, And your sins, have caused a hiding of face from you that he should-not hear.", "darby": "but your iniquities have separated between you and yourGod, and your sins have hid [his] face from you, that he doth not hear.", "twenty": "", "jps": "But your iniquities have separated between you and your G-d, and your sins have hid His face from you, that He will not hear.", "acv": "But your iniquities have separated between you and your God, and your sins have hid his face from you so that he will not hear.", "anderson": "", "haweis": "", "noyes": "But your iniquities have separated you from your God, And your sins have hidden his face from you, that he doth not hear.", "webster": "But your iniquities have separated between you and your God, and your sins have hid [his] face from you, that he will not hear.", "vulgate": "sed iniquitates vestrae diviserunt inter vos et Deum vestrum et peccata vestra absconderunt faciem eius a vobis ne exaudiret;", "brenton": "Nay, your iniquities separate between you and God, and because of your sins has he turned away his face from you, so as not to have mercy upon you."}}, {"v": 3, "ref": "59:3", "o": "כִּ֤י כַפֵּי/כֶם֙ נְגֹאֲל֣וּ בַ/דָּ֔ם וְ/אֶצְבְּעוֹתֵי/כֶ֖ם בֶּֽ/עָוֺ֑ן שִׂפְתֽוֹתֵי/כֶם֙ דִּבְּרוּ שֶׁ֔קֶר לְשׁוֹנְ/כֶ֖ם עַוְלָ֥ה תֶהְגֶּֽה", "en": {"kjv": "For your hands are defiled with blood, and your fingers with iniquity; your lips have spoken lies, your tongue hath muttered perverseness.", "web": "For your hands are defiled with blood, and your fingers with iniquity; your lips have spoken lies, your tongue mutters wickedness.", "bsb": "For your hands are stained with blood, and your fingers with iniquity; your lips have spoken lies, and your tongue mutters injustice.", "asv": "For your hands are defiled with blood, and your fingers with iniquity; your lips have spoken lies, your tongue muttereth wickedness.", "ylt": "For your hands have been polluted with blood, And your fingers with iniquity, Your lips have spoken falsehood, Your tongue perverseness doth mutter.", "dra": "For your hands are defiled with blood, and your fingers with iniquity: your lips have spoken lies, and your tongue uttereth iniquity.", "bbe": "For your hands are unclean with blood, and your fingers with sin; your lips have said false things, and your tongue gives out deceit.", "geneva": "For your handes are defiled with blood, and your fingers with iniquitie: your lips haue spoken lies and your tongue hath murmured iniquitie.", "wycliffe": "For whi youre hondis ben defoulid with blood, and youre fyngris with wickidnesse; youre lippis spaken leesyng, and youre tunge spekith wickidnesse.", "rotherham": "For, your hands, are defiled with blood, And, your fingers, with iniquity,—Your lips, have spoken falsehood, and Your tongue, muttereth, perversity.", "darby": "For your hands are stained with blood, and your fingers with iniquity; your lips speak lies, your tongue muttereth unrighteousness:", "twenty": "", "jps": "For your hands are defiled with blood, and your fingers with iniquity; your lips have spoken lies, your tongue muttereth wickedness.", "acv": "For your hands are defiled with blood, and your fingers with iniquity. Your lips have spoken lies. Your tongue mutters wickedness.", "anderson": "", "haweis": "", "noyes": "For your hands are polluted with blood, And your fingers with iniquity; Your lips speak falsehood, And your tongue muttereth wickedness.", "webster": "For your hands are defiled with blood, and your fingers with iniquity; your lips have spoken lies, your tongue hath uttered perverseness.", "vulgate": "manus enim vestrae pollutae sunt sanguine et digiti vestri iniquitate labia vestra locuta sunt mendacium et lingua vestra iniquitatem fatur;", "brenton": "For your hands are defiled with blood, and your fingers with sins; your lips also have spoken iniquity, and your tongue meditates unrighteousness."}}, {"v": 4, "ref": "59:4", "o": "אֵין קֹרֵ֣א בְ/צֶ֔דֶק וְ/אֵ֥ין נִשְׁפָּ֖ט בֶּ/אֱמוּנָ֑ה בָּט֤וֹחַ עַל תֹּ֨הוּ֙ וְ/דַבֶּר שָׁ֔וְא הָר֥וֹ עָמָ֖ל וְ/הוֹלֵ֥יד אָֽוֶן", "en": {"kjv": "None calleth for justice, nor any pleadeth for truth: they trust in vanity, and speak lies; they conceive mischief, and bring forth iniquity.", "web": "No one sues in righteousness, and no one pleads in truth: they trust in vanity, and speak lies; they conceive mischief, and give birth to iniquity.", "bsb": "No one calls for justice; no one pleads his case honestly. They rely on empty pleas; they tell lies; they conceive mischief and give birth to iniquity.", "asv": "None sueth in righteousness, and none pleadeth in truth: they trust in vanity, and speak lies; they conceive mischief, and bring forth iniquity.", "ylt": "There is none calling in righteousness, And there is none pleading in faithfulness, Trusting on emptiness, and speaking falsehood, Conceiving perverseness, and bearing iniquity.", "dra": "There is none that calleth upon justice, neither is there any one that judgeth truly: but they trust in a mere nothing, and speak vanities: they have conceived labour, and brought forth iniquity.", "bbe": "No one puts forward an upright cause, or gives a true decision: their hope is in deceit, and their words are false; they are with child with sin, and give birth to evil.", "geneva": "No man calleth for iustice: no man contendeth for trueth: they trust in vanitie, and speake vaine things: they conceiue mischiefe, and bring foorth iniquitie.", "wycliffe": "Noon is, that clepith riytfulnesse to help, and noon is, that demeth verili; but thei tristen in nouyt, and speken vanytees; thei conseyueden trauel, and childiden wickidnesse.", "rotherham": "None, sueth in righteousness, and None, pleadeth in faithfulness,—Men are trusting in confusion, And speaking vanity, Conceiving wickedness And bringing forth iniquity:", "darby": "none calleth for justice, none pleadeth in truthfulness. They trust in vanity, and speak falsehood; they conceive mischief, and bring forth iniquity.", "twenty": "", "jps": "None sueth in righteousness, and none pleadeth in truth; they trust in vanity, and speak lies, they conceive mischief, and bring forth iniquity.", "acv": "No man sues in righteousness, and no man pleads in truth. They trust in vanity, and speak lies. They conceive mischief, and bring forth iniquity.", "anderson": "", "haweis": "", "noyes": "No one bringeth his suit with justice, And no one pleadeth with truth; They trust in vain words, and speak lies; They conceive mischief, and bring forth destruction.", "webster": "None calleth for justice, nor [any] pleadeth for truth: they trust in vanity, and speak lies; they conceive mischief, and bring forth iniquity.", "vulgate": "non est qui invocet iustitiam neque est qui iudicet vere sed confidunt in nihili et loquuntur vanitates conceperunt laborem et pepererunt iniquitatem;", "brenton": "None speaks justly, neither is there true judgment: they trust in vanities, and speak empty words; for they conceive trouble, and bring forth iniquity."}}, {"v": 5, "ref": "59:5", "o": "בֵּיצֵ֤י צִפְעוֹנִי֙ בִּקֵּ֔עוּ וְ/קוּרֵ֥י עַכָּבִ֖ישׁ יֶאֱרֹ֑גוּ הָ/אֹכֵ֤ל מִ/בֵּֽיצֵי/הֶם֙ יָמ֔וּת וְ/הַ/זּוּרֶ֖ה תִּבָּקַ֥ע אֶפְעֶֽה", "en": {"kjv": "They hatch cockatrice’ eggs, and weave the spider’s web: he that eateth of their eggs dieth, and that which is crushed breaketh out into a viper.", "web": "They hatch adders’ eggs, and weave the spider’s web: he who eats of their eggs dies; and that which is crushed breaks out into a viper.", "bsb": "They hatch the eggs of vipers and weave a spider’s web. Whoever eats their eggs will die; crack one open, and a viper is hatched.", "asv": "They hatch adders’ eggs, and weave the spider’s web: he that eateth of their eggs dieth; and that which is crushed breaketh out into a viper.", "ylt": "Eggs of a viper they have hatched, And webs of a spider they weave, Whoso is eating their eggs doth die, And the crushed hatcheth a viper.", "dra": "They have broken the eggs of asps, and have woven the webs of spiders: he that shall eat of their eggs, shall die: and that which is brought out, shall be hatched into a basilisk.", "bbe": "They give birth to snake's eggs, and make spider's threads: whoever takes their eggs for food comes to his death, and the egg which is crushed becomes a poison-snake.", "geneva": "They hatch cockatrice egges, and weaue the spiders webbe: he that eateth of their egges, dieth, and that which is trode vpon, breaketh out into a serpent.", "wycliffe": "Thei han broke eiren of snakis, and maden webbis of an yreyn; he that etith of the eiren of hem, schal die, and that that is nurschid, ether brouyt forth, schal breke out in to a cocatrice.", "rotherham": "Viper’s eggs, do they hatch, Spider’s threads, do they weave,—He that eateth of their eggs, dieth, And, that which is crushed, bringeth forth an adder;", "darby": "They hatch serpents' eggs, and weave the spider's web: he that eateth of their eggs dieth, and that which is crushed breaketh out into a viper.", "twenty": "", "jps": "They hatch basilisks' eggs, and weave the spider's web; he that eateth of their eggs dieth, and that which is crushed breaketh out into a viper.", "acv": "They hatch adders' eggs, and weave the spider's web. He who eats of their eggs dies, and that which is crushed breaks out into a viper.", "anderson": "", "haweis": "", "noyes": "They hatch the eggs of the basilisk, And weave the web of the spider; He that eateth of their eggs dieth, And when one of them is crushed, a viper breaketh forth.", "webster": "They hatch cockatrice eggs, and weave the spider's web: he that eateth of their eggs dieth, and that which is crushed breaketh out into a viper.", "vulgate": "ova aspidum ruperunt et telas araneae texuerunt qui comederit de ovis eorum morietur et quod confotum est erumpet in regulum;", "brenton": "They have hatched asps' eggs, and weave a spider's web: and he that is going to eat of their eggs, having crushed an addled egg, has found also in it a basilisk."}}, {"v": 6, "ref": "59:6", "o": "קֽוּרֵי/הֶם֙ לֹא יִהְי֣וּ לְ/בֶ֔גֶד וְ/לֹ֥א יִתְכַּסּ֖וּ בְּ/מַֽעֲשֵׂי/הֶ֑ם מַֽעֲשֵׂי/הֶם֙ מַֽעֲשֵׂי אָ֔וֶן וּ/פֹ֥עַל חָמָ֖ס בְּ/כַפֵּי/הֶֽם", "en": {"kjv": "Their webs shall not become garments, neither shall they cover themselves with their works: their works are works of iniquity, and the act of violence is in their hands.", "web": "Their webs shall not become garments, neither shall they cover themselves with their works: their works are works of iniquity, and the act of violence is in their hands.", "bsb": "Their cobwebs cannot be made into clothing, and they cannot cover themselves with their works. Their deeds are sinful deeds, and acts of violence are in their hands.", "asv": "Their webs shall not become garments, neither shall they cover themselves with their works: their works are works of iniquity, and the act of violence is in their hands.", "ylt": "Their webs become not a garment, Nor do they cover themselves with their works, Their works are works of iniquity, And a deed of violence is in their hands.", "dra": "Their webs shall not be for clothing, neither shall they cover themselves with their works: their works are unprofitable works, and the work of iniquity is in their hands.", "bbe": "Their twisted threads will not make clothing, and their works will give them nothing for covering themselves: their works are works of sin, and violent acts are in their hands.", "geneva": "Their webbes shall be no garment, neither shall they couer themselues with their labours: for their workes are workes of iniquitie, and the worke of crueltie is in their handes.", "wycliffe": "The webbis of hem schulen not be in to cloth, nethir thei schulen be hilid with her werkis; the werkis of hem ben vnprofitable werkis, and the werk of wickidnesse is in the hondis of hem.", "rotherham": "Their threads, shall not become a garment, Neither shall they cover themselves with their fabrics,—Their fabrics, are fabrics of iniquity, Yea the product of violence is in their hands;", "darby": "Their webs shall not become garments, neither shall they cover themselves with their works; their works are works of iniquity, and the act of violence is in their hands.", "twenty": "", "jps": "Their webs shall not become garments, neither shall men cover themselves with their works; their works are works of iniquity, and the act of violence is in their hands.", "acv": "Their webs shall not become garments, nor shall they cover themselves with their works. Their works are works of iniquity, and the act of violence is in their hands.", "anderson": "", "haweis": "", "noyes": "Of their webs no garment is made, Nor can one cover himself with their work; Their works are works of iniquity, And the deed of violence is in their hands.", "webster": "Their webs shall not become garments, neither shall they cover themselves with their works: their works [are] works of iniquity, and the act of violence [is] in their hands.", "vulgate": "telae eorum non erunt in vestimentum neque operientur operibus suis opera eorum opera inutilia et opus iniquitatis in manibus eorum;", "brenton": "Their web shall not become a garment, nor shall they at all clothe themselves with their works; for their works are works of iniquity."}}, {"v": 7, "ref": "59:7", "o": "רַגְלֵי/הֶם֙ לָ/רַ֣ע יָרֻ֔צוּ וִֽ/ימַהֲר֔וּ לִ/שְׁפֹּ֖ךְ דָּ֣ם נָקִ֑י מַחְשְׁבֽוֹתֵי/הֶם֙ מַחְשְׁב֣וֹת אָ֔וֶן שֹׁ֥ד וָ/שֶׁ֖בֶר בִּ/מְסִלּוֹתָֽ/ם", "en": {"kjv": "Their feet run to evil, and they make haste to shed innocent blood: their thoughts are thoughts of iniquity; wasting and destruction are in their paths.", "web": "Their feet run to evil, and they make haste to shed innocent blood: their thoughts are thoughts of iniquity; desolation and destruction are in their paths.", "bsb": "Their feet run to evil; they are swift to shed innocent blood. Their thoughts are sinful thoughts; ruin and destruction lie in their wake.", "asv": "Their feet run to evil, and they make haste to shed innocent blood: their thoughts are thoughts of iniquity; desolation and destruction are in their paths.", "ylt": "Their feet to evil do run, And they haste to shed innocent blood, Their thoughts are thoughts of iniquity, Spoiling and destruction are in their highways.", "dra": "Their feet run to evil, and make haste to shed innocent blood: their thoughts are unprofitable thoughts: wasting and destruction are in their ways.", "bbe": "Their feet go quickly to evil, and they take delight in the death of the upright; their thoughts are thoughts of sin; wasting and destruction are in their ways.", "geneva": "Their feete runne to euill, and they make haste to shed innocent blood: their thoughts are wicked thoughts: desolation and destruction is in their paths.", "wycliffe": "The feet of hem rennen to yuel, and haasten to schede out innocent blood; the thouytis of hem ben vnprofitable thouytis; distriyng and defouling ben in the weies of hem.", "rotherham": "Their feet, to mischief, do run, And they speed to shed innocent blood,—Their devices, are devices of iniquity, Wasting and destruction, are in their high roads;", "darby": "Their feet run to evil, and they make haste to shed innocent blood; their thoughts are thoughts of iniquity; wasting and destruction are in their paths;", "twenty": "", "jps": "Their feet run to evil, and they make haste to shed innocent blood; their thoughts are thoughts of iniquity, desolation and destruction are in their paths.", "acv": "Their feet run to evil, and they make haste to shed innocent blood. Their thoughts are thoughts of iniquity. Desolation and destruction are in their paths.", "anderson": "", "haweis": "", "noyes": "Their feet run to evil; They make haste to shed innocent blood. Their thoughts are evil thoughts; Oppression and destruction are in their paths.", "webster": "Their feet run to evil, and they make haste to shed innocent blood: their thoughts [are] thoughts of iniquity; wasting and destruction [are] in their paths.", "vulgate": "pedes eorum ad malum currunt et festinant ut effundant sanguinem innocentem cogitationes eorum cogitationes inutiles vastitas et contritio in viis eorum;", "brenton": "And their feet run to wickedness, swift to shed blood; their thoughts also are thoughts of murder; destruction and misery are in their ways;"}}, {"v": 8, "ref": "59:8", "o": "דֶּ֤רֶךְ שָׁלוֹם֙ לֹ֣א יָדָ֔עוּ וְ/אֵ֥ין מִשְׁפָּ֖ט בְּ/מַעְגְּלוֹתָ֑/ם נְתִיבֽוֹתֵי/הֶם֙ עִקְּשׁ֣וּ לָ/הֶ֔ם כֹּ֚ל דֹּרֵ֣ךְ בָּ֔/הּ לֹ֥א יָדַ֖ע שָׁלֽוֹם", "en": {"kjv": "The way of peace they know not; and there is no judgment in their goings: they have made them crooked paths: whosoever goeth therein shall not know peace.", "web": "The way of peace they don’t know; and there is no justice in their goings: they have made them crooked paths; whoever goes therein does not know peace.", "bsb": "The way of peace they have not known, and there is no justice in their tracks. They have turned them into crooked paths; no one who treads on them will know peace.", "asv": "The way of peace they know not; and there is no justice in their goings: they have made them crooked paths; whosoever goeth therein doth not know peace.", "ylt": "A way of peace they have not known, And there is no judgment in their paths, Their paths they have made perverse for themselves, No treader in it hath known peace.", "dra": "They have not known the way of peace, and there is no judgment in their steps: their paths are become crooked to them, every one that treadeth in them knoweth no peace.", "bbe": "They have no knowledge of the way of peace, and there is no sense of what is right in their behaviour: they have made for themselves ways which are not straight; whoever goes in them has no knowledge of peace.", "geneva": "The way of peace they knowe not, and there is none equitie in their goings: they haue made them crooked paths: whosoeuer goeth therein, shall not knowe peace.", "wycliffe": "Thei knewen not the weie of pees, and doom is not in the goyngis of hem; the pathis of hem ben bowid to hem; ech that tredith in tho, knowith not pees.", "rotherham": "the way of well-being, have they not known, And there is no justice in their tracks,—Their paths, have they made crooked for themselves, None who treadeth therein knoweth well—being.", "darby": "the way of peace they know not, and there is no judgment in their goings; they have made their paths crooked: whoso goeth therein knoweth not peace.", "twenty": "", "jps": "The way of peace they know not, and there is no right in their goings; they have made them crooked paths, whosoever goeth therein doth not know peace.", "acv": "They do not know the way of peace, and there is no justice in their goings. They have made them crooked paths. Whoever goes in it does not know peace.", "anderson": "", "haweis": "", "noyes": "The way of peace they know not, Nor is there any justice in their steps; They have made for themselves crooked paths; Whoso goeth in them knoweth not peace.", "webster": "The way of peace they know not; and [there is] no judgment in their goings: they have made them crooked paths: whoever goeth therein shall not know peace.", "vulgate": "viam pacis nescierunt et non est iudicium in gressibus eorum semitae eorum incurvatae sunt eis omnis qui calcat in ea ignorat pacem;", "brenton": "and the way of peace they know not, neither is there judgment in their ways; for their paths by which they go are crooked, and they know not peace."}}, {"v": 9, "ref": "59:9", "o": "עַל כֵּ֗ן רָחַ֤ק מִשְׁפָּט֙ מִמֶּ֔/נּוּ וְ/לֹ֥א תַשִּׂיגֵ֖/נוּ צְדָקָ֑ה נְקַוֶּ֤ה לָ/אוֹר֙ וְ/הִנֵּה חֹ֔שֶׁךְ לִ/נְגֹה֖וֹת בָּ/אֲפֵל֥וֹת נְהַלֵּֽךְ", "en": {"kjv": "Therefore is judgment far from us, neither doth justice overtake us: we wait for light, but behold obscurity; for brightness, but we walk in darkness.", "web": "Therefore is justice far from us, neither does righteousness overtake us: we look for light, but, behold, darkness; for brightness, but we walk in obscurity.", "bsb": "Therefore justice is far from us, and righteousness does not reach us. We hope for light, but there is darkness; for brightness, but we walk in gloom.", "asv": "Therefore is justice far from us, neither doth righteousness overtake us: we look for light, but, behold, darkness; for brightness, but we walk in obscurity.", "ylt": "Therefore hath judgment been far from us, And righteousness reacheth us not, We wait for light, and lo, darkness, For brightness--in thick darkness we go,", "dra": "Therefore is judgment far from us, and justice shall not overtake us. We looked for light, and behold darkness: brightness, and we have walked in the dark.", "bbe": "For this cause our right is far from us, and righteousness does not overtake us: we are looking for light, but there is only the dark; for the shining of the sun, but our way is in the night.", "geneva": "Therefore is iudgement farre from vs, neither doeth iustice come neere vnto vs: we waite for light, but loe, it is darkenesse: for brightnesse, but we walke in darkenesse.", "wycliffe": "Therfor doom is made fer fro vs, and riytfulnesse schal not take vs; we abididen liyt, and lo! derknessis ben; we abididen schynyng, and we yeden in derknessis.", "rotherham": "For this cause, hath justice removed far from us, And righteousness overtaketh us not,—We wait for light, But lo! darkness, For brightness, In thick darkness, we walk:", "darby": "Therefore is justice far from us, and righteousness overtaketh us not: we wait for light, and behold darkness; for brightness, [but] we walk in obscurity.", "twenty": "", "jps": "Therefore is justice far from us, neither doth righteousness overtake us; we look for light, but behold darkness, for brightness, but we walk in gloom.", "acv": "Therefore justice is far from us, nor does righteousness overtake us. We look for light, but behold, darkness, for brightness, but we walk in obscurity.", "anderson": "", "haweis": "", "noyes": "Therefore is judgment far from us, And deliverance doth not overtake us. We look for light, and behold obscurity; For brightness, and we walk in darkness.", "webster": "Therefore is judgment far from us, neither doth justice overtake us: we wait for light, but behold obscurity; for brightness, [but] we walk in darkness.", "vulgate": "propter hoc elongatum est iudicium a nobis et non adprehendet nos iustitia expectavimus lucem et ecce tenebrae splendorem et in tenebris ambulavimus;", "brenton": "Therefore has judgment departed from them, and righteousness shall not overtake them: while they waited for light, darkness came upon them; while they waited for brightness, they walked in perplexity."}}, {"v": 10, "ref": "59:10", "o": "נְגַֽשְׁשָׁ֤ה כַֽ/עִוְרִים֙ קִ֔יר וּ/כְ/אֵ֥ין עֵינַ֖יִם נְגַשֵּׁ֑שָׁה כָּשַׁ֤לְנוּ בַֽ/צָּהֳרַ֨יִם֙ כַּ/נֶּ֔שֶׁף בָּ/אַשְׁמַנִּ֖ים כַּ/מֵּתִֽים", "en": {"kjv": "We grope for the wall like the blind, and we grope as if we had no eyes: we stumble at noonday as in the night; we are in desolate places as dead men.", "web": "We grope for the wall like the blind; yes, we grope as those who have no eyes: we stumble at noonday as in the twilight; among those who are lusty we are as dead men.", "bsb": "Like the blind, we feel our way along the wall, groping like those without eyes. We stumble at midday as in the twilight; among the vigorous we are like the dead.", "asv": "We grope for the wall like the blind; yea, we grope as they that have no eyes: we stumble at noonday as in the twilight; among them that are lusty we are as dead men.", "ylt": "We feel like the blind for the wall, Yea, as without eyes we feel, We have stumbled at noon as at twilight, In desolate places as the dead.", "dra": "We have groped for the wall, and like the blind we have groped as if we had no eyes: we have stumbled at noonday as in darkness, we are in dark places, as dead men.", "bbe": "We go on our way, like blind men feeling for the wall, even like those who have no eyes: we are running against things in daylight as if it was evening; our place is in the dark like dead men.", "geneva": "Wee grope for the wall like the blinde, and we grope as one without eyes: we stumble at the noone day as in the twilight: we are in solitarie places, as dead men.", "wycliffe": "We gropiden as blynde men the wal, and we as with outen iyen touchiden; we stumbliden in myddai, as in derknessis, in derk places, as deed men.", "rotherham": "We grope, as blind men for a wall, Yea, as men without eyes, do we grope,—We have stumbled at broad noon as though it were twilight, In desolate places like the dead!", "darby": "We grope for the wall like the blind, and we grope as if we had no eyes: we stumble at midday as in the twilight; amongst the flourishing we are as the dead.", "twenty": "", "jps": "We grope for the wall like the blind, yea, as they that have no eyes do we grope; we stumble at noonday as in the twilight; we are in dark places like the dead.", "acv": "We grope for the wall like the blind. Yea, we grope as those who have no eyes. We stumble at noonday as in the twilight. We are as dead men in desolate places.", "anderson": "", "haweis": "", "noyes": "We grope for the wall, like the blind; We feel our way, like those that are deprived of sight; We stumble at noonday as in the night; In the midst of fertile fields we are like the dead.", "webster": "We grope for the wall like the blind, and we grope as if [we had] no eyes: we stumble at noon day as in the night; [we are] in desolate places as dead [men].", "vulgate": "palpavimus sicut caeci parietem et quasi absque oculis adtrectavimus inpegimus meridie quasi in tenebris in caligosis quasi mortui;", "brenton": "They shall feel for the wall as blind men, and shall feel for it as if they had no eyes: and they shall feel at noon-day as at midnight; they shall groan as dying men."}}, {"v": 11, "ref": "59:11", "o": "נֶהֱמֶ֤ה כַ/דֻּבִּים֙ כֻּלָּ֔/נוּ וְ/כַ/יּוֹנִ֖ים הָגֹ֣ה נֶהְגֶּ֑ה נְקַוֶּ֤ה לַ/מִּשְׁפָּט֙ וָ/אַ֔יִן לִֽ/ישׁוּעָ֖ה רָחֲקָ֥ה מִמֶּֽ/נּוּ", "en": {"kjv": "We roar all like bears, and mourn sore like doves: we look for judgment, but there is none; for salvation, but it is far off from us.", "web": "We roar all like bears, and moan bitterly like doves: we look for justice, but there is none; for salvation, but it is far off from us.", "bsb": "We all growl like bears and moan like doves. We hope for justice, but find none, for salvation, but it is far from us.", "asv": "We roar all like bears, and moan sore like doves: we look for justice, but there is none; for salvation, but it is far off from us.", "ylt": "We make a noise as bears--all of us, And as doves we coo sorely; We wait for judgment, and there is none, For salvation--it hath been far from us.", "dra": "We shall roar all of us like bears, and shall lament as mournful doves. We have looked for judgment, and there is none: for salvation, and it is far from us.", "bbe": "We make noises of grief, like bears, and sad sounds like doves: we are looking for our right, but it is not there; for salvation, but it is far from us.", "geneva": "We roare all like beares, and mourne like dooues: wee looke for equitie, but there is none: for health, but it is farre from vs.", "wycliffe": "Alle we schulen rore as beeris, and we schulen weile thenkynge as culueris; we abididen doom, and noon is; we abididen helthe, and it is maad fer fro vs.", "rotherham": "We growl like bears all of us, And, like doves, do we, mournfully coo,—We wait For justice, and there is none, For salvation it is far from us!", "darby": "We roar all like bears, and mourn grievously like doves: we look for judgment, and there is none; for salvation, [but] it is far from us.", "twenty": "", "jps": "We all growl like bears, and mourn sore like doves; we look for right, but there is none; for salvation, but it is far off from us.", "acv": "We all roar like bears, and moan greatly like doves. We look for justice, but there is none, for salvation, but it is far off from us.", "anderson": "", "haweis": "", "noyes": "We groan, all of us, like bears, And like doves we make a continued moan; We look for judgment, and it cometh not; For salvation, and it is far from us.", "webster": "We all roar like bears, and mourn bitterly like doves: we look for judgment, but [there is] none; for salvation, [but] it is far from us.", "vulgate": "rugiemus quasi ursi omnes et quasi columbae meditantes gememus expectavimus iudicium et non est salutem et elongata est a nobis;", "brenton": "They shall proceed together as a bear and as a dove: we have waited for judgment, and there is no salvation, it is gone far from us."}}, {"v": 12, "ref": "59:12", "o": "כִּֽי רַבּ֤וּ פְשָׁעֵ֨י/נוּ֙ נֶגְדֶּ֔/ךָ וְ/חַטֹּאותֵ֖י/נוּ עָ֣נְתָה בָּ֑/נוּ כִּֽי פְשָׁעֵ֣י/נוּ אִתָּ֔/נוּ וַ/עֲוֺנֹתֵ֖י/נוּ יְדַֽעֲנֽוּ/ם", "en": {"kjv": "For our transgressions are multiplied before thee, and our sins testify against us: for our transgressions are with us; and as for our iniquities, we know them;", "web": "For our transgressions are multiplied before you, and our sins testify against us; for our transgressions are with us, and as for our iniquities, we know them:", "bsb": "For our transgressions are multiplied before You, and our sins testify against us. Our transgressions are indeed with us, and we know our iniquities:", "asv": "For our transgressions are multiplied before thee, and our sins testify against us; for our transgressions are with us, and as for our iniquities, we know them:", "ylt": "For our transgressions have been multiplied before Thee, And our sins have testified against us, For our transgressions are with us, And our iniquities--we have known them.", "dra": "For our iniquities are multiplied before thee, and our sins have testified against us: for our wicked doings are with us, and have known our iniquities:", "bbe": "For our evil doings are increased before you, and our sins give witness against us: for our evil doings are with us, and we have knowledge of our sins:", "geneva": "For our trespasses are many before thee, and our sinnes testifie against vs: for our trespasses are with vs, and we knowe our iniquities", "wycliffe": "For whi oure wickidnessis ben multiplied bifore thee, and oure synnes answeriden to vs; for our grete trespassis ben with vs, and we knewen oure wickidnessis,", "rotherham": "For our transgressions have multiplied before thee, And, our sins, have witnessed against us,—For, our transgressions, are with us, And as for our iniquities, we acknowledge them:", "darby": "For our transgressions are multiplied before thee, and our sins testify against us; for our transgressions are with us; and our iniquities, we know them:", "twenty": "", "jps": "For our transgressions are multiplied before Thee, and our sins testify against us; for our transgressions are present to us, and as for our iniquities, we know them:", "acv": "For our transgressions are multiplied before thee, and our sins testify against us. For our transgressions are with us, and as for our iniquities, we know them:", "anderson": "", "haweis": "", "noyes": "For our transgressions are multiplied before thee, And our sins testify against us! For our transgressions are not hidden from us, And our iniquities we know.", "webster": "For our transgressions are multiplied before thee, and our sins testify against us: for our transgressions [are] with us; and [as for] our iniquities, we know them;", "vulgate": "multiplicatae sunt enim iniquitates nostrae coram te et peccata nostra responderunt nobis quia scelera nostra nobiscum et iniquitates nostras cognovimus;", "brenton": "For our iniquity is great before thee, and our sins have risen up against us: for our iniquities are in us, and we know our unrighteous deeds."}}, {"v": 13, "ref": "59:13", "o": "פָּשֹׁ֤עַ וְ/כַחֵשׁ֙ בַּֽ/יהוָ֔ה וְ/נָס֖וֹג מֵ/אַחַ֣ר אֱלֹהֵ֑י/נוּ דַּבֶּר עֹ֣שֶׁק וְ/סָרָ֔ה הֹר֧וֹ וְ/הֹג֛וֹ מִ/לֵּ֖ב דִּבְרֵי שָֽׁקֶר", "en": {"kjv": "In transgressing and lying against the Lord, and departing away from our God, speaking oppression and revolt, conceiving and uttering from the heart words of falsehood.", "web": "transgressing and denying Yahweh, and turning away from following our God, speaking oppression and revolt, conceiving and uttering from the heart words of falsehood.", "bsb": "rebelling and denying the LORD, turning away from our God, speaking oppression and revolt, conceiving and uttering lies from the heart.", "asv": "transgressing and denying Jehovah, and turning away from following our God, speaking oppression and revolt, conceiving and uttering from the heart words of falsehood.", "ylt": "Transgressing, and lying against Jehovah, And removing from after our God, Speaking oppression and apostasy, Conceiving and uttering from the heart Words of falsehood.", "dra": "In sinning and lying against the Lord: and we have turned away so that we went not after our God, but spoke calumny and transgression: we have conceived, and uttered from the heart, words of falsehood.", "bbe": "We have gone against the Lord, and been false to him, turning away from our God, our words have been uncontrolled, and in our hearts are thoughts of deceit.", "geneva": "In trespassing and lying against the Lord, and wee haue departed away from our God, and haue spoken of crueltie and rebellion, conceiuing and vttering out of the heart false matters.", "wycliffe": "to do synne, and to lie ayens the Lord. And we ben turned awei, that we yeden not aftir the bak of oure God, that we speken fals caleng, and trespassyng. We conseyueden, and spaken of herte wordis of leesyng; and doom was turned abak,", "rotherham": "Transgressing, and denying Yahweh, And turning away from following our God,—Speaking oppression and revolt, Conceiving, and muttering from the heart, words of falsehood.", "darby": "in transgressing and lying against Jehovah, and departing away from ourGod, speaking oppression and revolt, conceiving and uttering from the heart words of falsehood.", "twenty": "", "jps": "Transgressing and denying HaShem, and turning away from following our G-d, speaking oppression and perverseness, conceiving and uttering from the heart words of falsehood.", "acv": "transgressing and denying Jehovah, and turning away from following our God, speaking oppression and revolt, conceiving and uttering from the heart words of falsehood.", "anderson": "", "haweis": "", "noyes": "We have rebelled, and proved false to Jehovah; We have departed from our God; We have spoken violence and rebellion; Our hearts have conceived and brought forth words of falsehood.", "webster": "In transgressing and lying against the LORD, and departing away from our God, speaking oppression and revolt, conceiving and uttering from the heart words of falsehood.", "vulgate": "peccare et mentiri contra Dominum et aversi sumus ne iremus post tergum Dei nostri ut loqueremur calumniam et transgressionem concepimus et locuti sumus de corde verba mendacii;", "brenton": "We have sinned, and dealt falsely, and revolted from our God: we have spoken unrighteous words, and have been disobedient; we have conceived and uttered from our heart unrighteous words."}}, {"v": 14, "ref": "59:14", "o": "וְ/הֻסַּ֤ג אָחוֹר֙ מִשְׁפָּ֔ט וּ/צְדָקָ֖ה מֵ/רָח֣וֹק תַּעֲמֹ֑ד כִּֽי כָשְׁלָ֤ה בָֽ/רְחוֹב֙ אֱמֶ֔ת וּ/נְכֹחָ֖ה לֹא תוּכַ֥ל לָ/בֽוֹא", "en": {"kjv": "And judgment is turned away backward, and justice standeth afar off: for truth is fallen in the street, and equity cannot enter.", "web": "Justice is turned away backward, and righteousness stands afar off; for truth is fallen in the street, and uprightness can’t enter.", "bsb": "So justice is turned away, and righteousness stands at a distance. For truth has stumbled in the public square, and honesty cannot enter.", "asv": "And justice is turned away backward, and righteousness standeth afar off; for truth is fallen in the street, and uprightness cannot enter.", "ylt": "And removed backward is judgment, And righteousness afar off standeth, For truth hath been feeble in the street, And straightforwardness is not able to enter,", "dra": "And judgment is turned away backward, and justice hath stood far off: because truth hath fallen down in the street, and equity could not come in.", "bbe": "And the right is turned back, and righteousness is far away: for good faith is not to be seen in the public places, and upright behaviour may not come into the town.", "geneva": "Therefore iudgement is turned backewarde, and iustice standeth farre off: for trueth is fallen in the streete, and equitie cannot enter.", "wycliffe": "and riytfulnesse stood fer; for whi treuthe felle doun in the street, and equite miyt not entre.", "rotherham": "So then there hath been a driving back of justice, And righteousness, afar off, standeth,—For truth, hath stumbled in the broad-way, And, right, cannot enter;", "darby": "And judgment is turned away backward, and righteousness standeth afar off; for truth stumbleth in the street, and uprightness cannot enter.", "twenty": "", "jps": "And justice is turned away backward, and righteousness standeth afar off; for truth hath stumbled in the broad place, and uprightness cannot enter.", "acv": "And justice is turned away backward, and righteousness stands afar off. For truth has fallen in the street, and uprightness cannot enter.", "anderson": "", "haweis": "", "noyes": "And justice is turned back, And equity standeth afar off, For truth falleth in the gate, And rectitude cannot enter.", "webster": "And judgment is turned away backward, and justice standeth afar off: for truth is fallen in the street, and equity cannot enter.", "vulgate": "et conversum est retrorsum iudicium et iustitia longe stetit quia corruit in platea veritas et aequitas non potuit ingredi;", "brenton": "And we have turned judgment back, and righteousness has departed afar off: for truth is consumed in their ways, and they could not pass by a straight path."}}, {"v": 15, "ref": "59:15", "o": "וַ/תְּהִ֤י הָֽ/אֱמֶת֙ נֶעְדֶּ֔רֶת וְ/סָ֥ר מֵ/רָ֖ע מִשְׁתּוֹלֵ֑ל וַ/יַּ֧רְא יְהוָ֛ה וַ/יֵּ֥רַע בְּ/עֵינָ֖י/ו כִּֽי אֵ֥ין מִשְׁפָּֽט", "en": {"kjv": "Yea, truth faileth; and he that departeth from evil maketh himself a prey: and the Lord saw it, and it displeased him that there was no judgment.", "web": "Yes, truth is lacking; and he who departs from evil makes himself a prey. Yahweh saw it, and it displeased him that there was no justice.", "bsb": "Truth is missing, and whoever turns from evil becomes prey. The LORD looked and was displeased that there was no justice.", "asv": "Yea, truth is lacking; and he that departeth from evil maketh himself a prey. And Jehovah saw it, and it displeased him that there was no justice.", "ylt": "And the truth is lacking, And whoso is turning aside from evil, Is making himself a spoil. And Jehovah seeth, and it is evil in His eyes, That there is no judgment.", "dra": "And truth hath been forgotten: and he that departed from evil, lay open to be a prey: and the Lord saw, and it appeared evil in his eyes, because there is no judgment.", "bbe": "Yes, faith is gone; and he whose heart is turned from evil comes into the power of the cruel: and the Lord saw it, and he was angry that there was no one to take up their cause.", "geneva": "Yea, trueth faileth, and hee that refraineth from euill, maketh himselfe a praye: and when the Lord sawe it, it displeased him, that there was no iudgement.", "wycliffe": "And treuthe was maad in to foryetyng, and he that yede awei fro yuel, was opyn to robbyng. And the Lord siy, and it apperide yuel in hise iyen, for ther is no doom.", "rotherham": "And the truth hath been found missing, And he that hath turned away from wrong is liable to be despoiled, And when, Yahweh, looked, Then was it grievous in his eyes that there was no justice:", "darby": "And truth faileth; and he that departeth from evil maketh himself a prey. And Jehovah saw [it], and it was evil in his sight that there was no judgment.", "twenty": "", "jps": "And truth is lacking, and he that departeth from evil maketh himself a prey. And HaShem saw it, and it displeased Him that there was no justice;", "acv": "Yea, truth is lacking, and he who departs from evil makes himself a prey. And Jehovah saw it, and it displeased him that there was no justice.", "anderson": "", "haweis": "", "noyes": "Truth is not to be found, And he that departeth from evil is plundered; And Jehovah saw it, And it displeased him that there was no justice.", "webster": "Yes, truth faileth; and he [that] departeth from evil maketh himself a prey: and the LORD saw [it], and it displeased him that [there was] no judgment.", "vulgate": "et facta est veritas in oblivione et qui recessit a malo praedae patuit et vidit Dominus et malum apparuit in oculis eius quia non est iudicium;", "brenton": "And truth has been taken away, and they have turned aside their mind from understanding. And the Lord saw it, and it pleased him not that there was no judgment."}}, {"v": 16, "ref": "59:16", "o": "וַ/יַּרְא֙ כִּֽי אֵ֣ין אִ֔ישׁ וַ/יִּשְׁתּוֹמֵ֖ם כִּ֣י אֵ֣ין מַפְגִּ֑יעַ וַ/תּ֤וֹשַֽׁע ל/וֹ֙ זְרֹע֔/וֹ וְ/צִדְקָת֖/וֹ הִ֥יא סְמָכָֽתְ/הוּ", "en": {"kjv": "And he saw that there was no man, and wondered that there was no intercessor: therefore his arm brought salvation unto him; and his righteousness, it sustained him.", "web": "He saw that there was no man, and wondered that there was no intercessor: therefore his own arm brought salvation to him; and his righteousness, it upheld him.", "bsb": "He saw that there was no man; He was amazed that there was no one to intercede. So His own arm brought salvation, and His own righteousness sustained Him.", "asv": "And he saw that there was no man, and wondered that there was no intercessor: therefore his own arm brought salvation unto him; and his righteousness, it upheld him.", "ylt": "And He seeth that there is no man, And is astonished that there is no intercessor, And His own arm giveth salvation to Him, And His righteousness--it sustained Him.", "dra": "And he saw that there is not a man: and he stood astonished, because there is none to oppose himself: and his own arm brought salvation to him, and his own justice supported him.", "bbe": "And he saw that there was no man, and was surprised that there was no one to take up their cause: so his arm gave salvation, and he made righteousness his support.", "geneva": "And when he sawe that there was no man, hee wondered that none woulde offer him selfe. Therefore his arme did saue it, and his righteousnes it selfe did sustaine it.", "wycliffe": "And God siy, that a man is not, and he was angwischid, for noon is that renneth to. And his arm schal saue to hym silf, and his riytfulnesse it silf schal conferme hym.", "rotherham": "When he saw that there was no mighty man, Then was he astonished that there was none to interpose,—So his own arm brought him salvation, And his own righteousness, the same, upheld him;", "darby": "And he saw that there was no man, and he wondered that there was no intercessor; and his arm brought him salvation, and his righteousness, it sustained him.", "twenty": "", "jps": "And He saw that there was no man, and was astonished that there was no intercessor; therefore His own arm brought salvation unto Him; and His righteousness, it sustained Him;", "acv": "And he saw that there was no man, and wondered that there was no intercessor. Therefore his own arm brought salvation to him. And his righteousness, it upheld him.", "anderson": "", "haweis": "", "noyes": "He saw that there was none to help, And wondered that there was none to interpose; Then his own arm wrought salvation for him, And his righteousness it supported him.", "webster": "And he saw that [there was] no man, and wondered that [there was] no intercessor: therefore his arm brought salvation to him; and his righteousness, it sustained him.", "vulgate": "et vidit quia non est vir et aporiatus est quia non est qui occurrat et salvavit sibi brachium suum et iustitia eius ipsa confirmavit eum;", "brenton": "And he looked, and there was no man, and he observed, and there was none to help: so he defended them with his arm, and stablished them with his mercy."}}, {"v": 17, "ref": "59:17", "o": "וַ/יִּלְבַּ֤שׁ צְדָקָה֙ כַּ/שִּׁרְיָ֔ן וְ/כ֥וֹבַע יְשׁוּעָ֖ה בְּ/רֹאשׁ֑/וֹ וַ/יִּלְבַּ֞שׁ בִּגְדֵ֤י נָקָם֙ תִּלְבֹּ֔שֶׁת וַ/יַּ֥עַט כַּ/מְעִ֖יל קִנְאָֽה", "en": {"kjv": "For he put on righteousness as a breastplate, and an helmet of salvation upon his head; and he put on the garments of vengeance for clothing, and was clad with zeal as a cloke.", "web": "He put on righteousness as a breastplate, and a helmet of salvation on his head; and he put on garments of vengeance for clothing, and was clad with zeal as a mantle.", "bsb": "He put on righteousness like a breastplate, and the helmet of salvation on His head; He put on garments of vengeance and wrapped Himself in a cloak of zeal.", "asv": "And he put on righteousness as a breastplate, and a helmet of salvation upon his head; and he put on garments of vengeance for clothing, and was clad with zeal as a mantle.", "ylt": "And He putteth on righteousness as a breastplate, And an helmet of salvation on His head, And He putteth on garments of vengeance for clothing, And is covered, as with an upper-robe, with zeal.", "dra": "He put on justice as a breastplate, and a helmet of salvation upon his head: he put on the garments of vengeance, and was clad with zeal as with a cloak.", "bbe": "Yes, he put on righteousness as a breastplate, and salvation as a head-dress; and he put on punishment as clothing, and wrath as a robe.", "geneva": "For he put on righteousnes, as an habergeon, and an helmet of saluation vpon his head, and he put on the garments of vengeance for clothing, and was clad with zeale as a cloke.", "wycliffe": "He is clothid with riytfulnesse as with an harburioun, and the helm of helthe is in his heed; he is clothid with clothis of veniaunce, and he is hilid as with a mentil of feruent worchyng.", "rotherham": "And he put on Righteousness as a coat of mail, And a helmet of victory upon his head,—And he put on the garments of avenging, for clothing, And wrapped about him as a cloak—jealousy,", "darby": "And he put on righteousness as a breastplate, and a helmet of salvation upon his head; and he put on garments of vengeance [for] clothing, and was clad with zeal as a cloak.", "twenty": "", "jps": "And He put on righteousness as a coat of mail, and a helmet of salvation upon His head, and He put on garments of vengeance for clothing, and was clad with zeal as a cloak.", "acv": "And he put on righteousness as a breastplate, and a helmet of salvation upon his head. And he put on garments of vengeance for clothing, and was clad with zeal as a mantle.", "anderson": "", "haweis": "", "noyes": "He put on righteousness as a breastplate, And the helmet of salvation upon his head; He put on garments of vengeance for his clothing, And clad himself with zeal, as with a mantle.", "webster": "For he put on righteousness as a breast-plate, and a helmet of salvation upon his head; and he put on the garments of vengeance [for] clothing, and was clad with zeal as a cloke.", "vulgate": "indutus est iustitia ut lorica et galea salutis in capite eius indutus est vestimentis ultionis et opertus est quasi pallio zeli;", "brenton": "And he put on righteousness as a breast-plate, and placed the helmet of salvation on his head; and he clothed himself with the garment of vengeance, and with his cloak,"}}, {"v": 18, "ref": "59:18", "o": "כְּ/עַ֤ל גְּמֻלוֹת֙ כְּ/עַ֣ל יְשַׁלֵּ֔ם חֵמָ֣ה לְ/צָרָ֔י/ו גְּמ֖וּל לְ/אֹֽיְבָ֑י/ו לָ/אִיִּ֖ים גְּמ֥וּל יְשַׁלֵּֽם", "en": {"kjv": "According to their deeds, accordingly he will repay, fury to his adversaries, recompence to his enemies; to the islands he will repay recompence.", "web": "According to their deeds, accordingly he will repay, wrath to his adversaries, recompense to his enemies; to the islands he will repay recompense.", "bsb": "So He will repay according to their deeds: fury to His enemies, retribution to His foes, and recompense to the islands.", "asv": "According to their deeds, accordingly he will repay, wrath to his adversaries, recompense to his enemies; to the islands he will repay recompense.", "ylt": "According to deeds--so He repayeth. Fury to His adversaries, their deed to His enemies, To the isles their deed He repayeth.", "dra": "As unto revenge, as it were to repay wrath to his adversaries, and a reward to his enemies: he will repay the like to the islands.", "bbe": "He will give them the right reward of their doings, wrath to his attackers, punishment to his haters, and even on the sea-lands he will send punishment.", "geneva": "As to make recompence, as to requite the furie of the aduersaries with a recompence to his enemies: he will fully repaire the ylands.", "wycliffe": "As to veniaunce, as to yeldyng of indignacioun to hise enemyes, and to quityng of tyme to hise aduersaries, he schal yelde while to ylis.", "rotherham": "According to their deeds, accordingly, will he repay, Indignation to his adversaries, Recompense to his enemies,—To the Coastlands—recompense, will he repay:", "darby": "According to deeds, so will he repay: fury to his adversaries, recompence to his enemies; to the islands he will repay recompence.", "twenty": "", "jps": "According to their deeds, accordingly He will repay, fury to His adversaries, recompense to His enemies; to the islands He will repay recompense.", "acv": "According to their deeds, accordingly he will repay, wrath to his adversaries, recompense to his enemies. He will repay recompense to the islands.", "anderson": "", "haweis": "", "noyes": "According to their deeds will he repay them,—Wrath to his adversaries, recompense to his enemies; To the distant coasts will he repay a recompense.", "webster": "According to [their] deeds, accordingly he will repay, fury to his adversaries, recompense to his enemies; to the isles he will repay recompense.", "vulgate": "sicut ad vindictam quasi ad retributionem indignationis hostibus suis et vicissitudinem inimicis suis insulis vicem reddet;", "brenton": "as one about to render a recompence, even reproach to his adversaries."}}, {"v": 19, "ref": "59:19", "o": "וְ/יִֽירְא֤וּ מִֽ/מַּעֲרָב֙ אֶת שֵׁ֣ם יְהוָ֔ה וּ/מִ/מִּזְרַח שֶׁ֖מֶשׁ אֶת כְּבוֹד֑/וֹ כִּֽי יָב֤וֹא כַ/נָּהָר֙ צָ֔ר ר֥וּחַ יְהוָ֖ה נֹ֥סְסָה בֽ/וֹ", "en": {"kjv": "So shall they fear the name of the Lord from the west, and his glory from the rising of the sun. When the enemy shall come in like a flood, the Spirit of the Lord shall lift up a standard against him.", "web": "So shall they fear Yahweh’s name from the west, and his glory from the rising of the sun; for he will come as a rushing stream, which the breath of Yahweh drives.", "bsb": "So shall they fear the name of the LORD where the sun sets, and His glory where it rises. For He will come like a raging flood, driven by the breath of the LORD.", "asv": "So shall they fear the name of Jehovah from the west, and his glory from the rising of the sun; for he will come as a rushing stream, which the breath of Jehovah driveth.", "ylt": "And they fear from the west the name of Jehovah, And from the rising of the sun--His honour, When come in as a flood doth an adversary, The Spirit of Jehovah hath raised an ensign against him.", "dra": "And they from the west, shall fear the name of the Lord: and they from the rising of the sun, his glory when he shall come as a violent stream, which the spirit of the Lord driveth on:", "bbe": "So they will see the name of the Lord from the west, and his glory from the east: for he will come like a rushing stream, forced on by a wind of the Lord.", "geneva": "So shall they feare the Name of the Lord from the West, and his glory from the rising of the sunne: for the enemie shall come like a flood: but the Spirit of the Lord shall chase him away.", "wycliffe": "And thei that ben at the west, schulen drede the name of the Lord, and thei that ben at the risyng of the sunne, schulen drede the glorie of hym; whanne he schal come as a violent flood, whom the spirit of the Lord compellith.", "rotherham": "That they may revere—From the West the name of Yahweh, And from the Rising of the Sun his glory, For he will come in like a rushing stream, the breath of Yahweh, driving it on;", "darby": "And they shall fear the name of Jehovah from the west, and from the rising of the sun, his glory. When the adversary shall come in like a flood, the Spirit of Jehovah will lift up a banner against him.", "twenty": "", "jps": "So shall they fear the name of HaShem from the west, and His glory from the rising of the sun; for distress will come in like a flood, which the breath of HaShem driveth.", "acv": "So they shall fear the name of Jehovah from the west, and his glory from the rising of the sun. For he will come as a rushing stream, which the breath of Jehovah drives.", "anderson": "", "haweis": "", "noyes": "They in the west shall fear the name of Jehovah, And they in the rising of the sun his glory, When he cometh like a river straitened in its course, Which a strong wind driveth along.", "webster": "So shall they fear the name of the LORD from the west, and his glory from the rising of the sun. When the enemy shall come in like a flood, the Spirit of the LORD will lift up a standard against him.", "vulgate": "et timebunt qui ab occidente nomen Domini et qui ab ortu solis gloriam eius cum venerit quasi fluvius violentus quem spiritus Domini cogit;", "brenton": "So shall they of the west fear the name of the Lord, and they that come from the rising of the sun his glorious name: for the wrath of the Lord shall come as a mighty river, it shall come with fury."}}, {"v": 20, "ref": "59:20", "o": "וּ/בָ֤א לְ/צִיּוֹן֙ גּוֹאֵ֔ל וּ/לְ/שָׁבֵ֥י פֶ֖שַׁע בְּ/יַֽעֲקֹ֑ב נְאֻ֖ם יְהוָֽה", "en": {"kjv": "And the Redeemer shall come to Zion, and unto them that turn from transgression in Jacob, saith the Lord.", "web": "“A Redeemer will come to Zion, and to those who turn from disobedience in Jacob,” says Yahweh.", "bsb": "“The Redeemer will come to Zion, to those in Jacob who turn from transgression,” declares the LORD.", "asv": "And a Redeemer will come to Zion, and unto them that turn from transgression in Jacob, saith Jehovah.", "ylt": "And come to Zion hath a redeemer, Even to captives of transgression in Jacob, An affirmation of Jehovah.", "dra": "And there shall come a redeemer to Sion, and to them that return from iniquity in Jacob, saith the Lord.", "bbe": "And as a saviour he will come to Zion, turning away sin from Jacob, says the Lord.", "geneva": "And the Redeemer shall come vnto Zion, and vnto them that turne from iniquitie in Iaakob, saith the Lord.", "wycliffe": "Whan ayen biere schal come to Syon, and to hem that goen ayen fro wickidnesse in Jacob, seith the Lord.", "rotherham": "So shall come in for Zion, a Redeemer, Even for such as are turning from transgression in Jacob,—Declareth Yahweh.", "darby": "And the Redeemer will come to Zion, and unto them that turn from transgression in Jacob, saith Jehovah.", "twenty": "", "jps": "And a redeemer will come to Zion, and unto them that turn from transgression in Jacob, saith HaShem.", "acv": "And he who redeems will come to Zion, and to those who turn from transgression in Jacob, says Jehovah.", "anderson": "", "haweis": "", "noyes": "Yet shall a redeemer come to Zion, For them that turn from their transgressions in Jacob, saith Jehovah.", "webster": "And the Redeemer will come to Zion, and to them that turn from transgression in Jacob, saith the LORD.", "vulgate": "et venerit Sion redemptor et eis qui redeunt ab iniquitate in Iacob dicit Dominus;", "brenton": "And the deliverer shall come for Sion's sake, and shall turn away ungodliness from Jacob."}}, {"v": 21, "ref": "59:21", "o": "וַ/אֲנִ֗י זֹ֣את בְּרִיתִ֤/י אוֹתָ/ם֙ אָמַ֣ר יְהוָ֔ה רוּחִ/י֙ אֲשֶׁ֣ר עָלֶ֔י/ךָ וּ/דְבָרַ֖/י אֲשֶׁר שַׂ֣מְתִּי בְּ/פִ֑י/ךָ לֹֽא יָמ֡וּשׁוּ מִ/פִּי/ךָ֩ וּ/מִ/פִּ֨י זַרְעֲ/ךָ֜ וּ/מִ/פִּ֨י זֶ֤רַע זַרְעֲ/ךָ֙ אָמַ֣ר יְהוָ֔ה מֵ/עַתָּ֖ה וְ/עַד עוֹלָֽם", "en": {"kjv": "As for me, this is my covenant with them, saith the Lord; My spirit that is upon thee, and my words which I have put in thy mouth, shall not depart out of thy mouth, nor out of the mouth of thy seed, nor out of the mouth of thy seed’s seed, saith the Lord, from henceforth and for ever.", "web": "“As for me, this is my covenant with them,” says Yahweh. “My Spirit who is on you, and my words which I have put in your mouth, shall not depart out of your mouth, nor out of the mouth of your seed, nor out of the mouth of your seed’s seed,” says Yahweh, “from henceforth and forever.”", "bsb": "“As for Me, this is My covenant with them,” says the LORD. “My Spirit will not depart from you, and My words that I have put in your mouth will not depart from your mouth or from the mouths of your children and grandchildren, from now on and forevermore,” says the LORD.", "asv": "And as for me, this is my covenant with them, saith Jehovah: my Spirit that is upon thee, and my words which I have put in thy mouth, shall not depart out of thy mouth, nor out of the mouth of thy seed, nor out of the mouth of thy seed’s seed, saith Jehovah, from henceforth and for ever.", "ylt": "And I--this is My covenant with them, said Jehovah, My Spirit that is on thee, And My words that I have put in thy mouth, Depart not from thy mouth, And from the mouth of thy seed, And from the mouth of thy seed's seed, said Jehovah, From henceforth unto the age!", "dra": "This is my covenant with them, saith the Lord: My spirit that is in thee, and my words that I have put in thy mouth, shall not depart out of thy mouth, nor out of the mouth of thy seed, nor out of the mouth of thy seed's seed, saith the Lord, from henceforth and for ever.", "bbe": "And as for me, this is my agreement with them, says the Lord: my spirit which is on you, and my words which I have put in your mouth, will not go away from your mouth, or from the mouth of your seed, or from the mouth of your seed's seed, says the Lord, from now and for ever.", "geneva": "And I will make this my couenant with them, saith the Lord. My Spirit that is vpon thee, and my wordes, which I haue put in thy mouth, shall not depart out of thy mouth, nor out of the mouth of thy seede, nor out of the mouth of the seede of thy seede, saith the Lord, from hencefoorth euen for euer.", "wycliffe": "This is my boond of pees with hem, seith the Lord; My spirit which is in thee, and my wordis whiche Y haue set in thi mouth, schulen not go awei fro thi mouth, and fro the mouth of thi seed, seith the Lord, fro hennus forth and til into with outen ende.", "rotherham": "And as for me, this, shall be my covenant with them, Saith Yahweh: My spirit that is upon thee, And my words which I have put in thy mouth,—Shall not be taken out of thy mouth—Nor out of the mouth of thy seed. Nor out of the mouth of thy seeds seed, Saith Yahweh, From henceforth even unto times age-abiding.", "darby": "And as for me, this is my covenant with them, saith Jehovah: My spirit that is upon thee, and my words which I have put in thy mouth, shall not depart out of thy mouth, nor out of the mouth of thy seed, nor out of the mouth of thy seed's seed, saith Jehovah, from henceforth and for ever.", "twenty": "", "jps": "And as for Me, this is My covenant with them, saith HaShem; My spirit that is upon thee, and My words which I have put in thy mouth, shall not depart out of thy mouth, nor out of the mouth of thy seed, nor out of the mouth of thy seed's seed, saith HaShem, from henceforth and for ever.", "acv": "And as for me, this is my covenant with them, says Jehovah: My Spirit that is upon thee, and my words which I have put in thy mouth, shall not depart out of thy mouth, nor out of the mouth of thy seed, nor out of the mouth of thy seed's seed, says Jehovah, from henceforth and forever.", "anderson": "", "haweis": "", "noyes": "And as for me, this is my covenant with them, saith Jehovah: My spirit, which is upon thee, And my words, which I have put in thy mouth, They shall not depart from thy mouth, Nor from the mouth of thy sons, Nor from the mouth of thy sons’ sons, saith Jehovah, From this time forth forever.", "webster": "As for me, this [is] my covenant with them, saith the LORD; My spirit that [is] upon thee, and my words which I have put in thy mouth, shall not depart out of thy mouth, nor out of the mouth of thy seed, nor out of the mouth of thy seed's seed, saith the LORD, from henceforth and for ever.", "vulgate": "hoc foedus meum cum eis dicit Dominus spiritus meus qui est in te et verba mea quae posui in ore tuo non recedent de ore tuo et de ore seminis tui et de ore seminis seminis tui dixit Dominus amodo et usque in sempiternum;", "brenton": "And this shall be my covenant with them, said the Lord; My Spirit which is upon thee, and the words which I have put in thy mouth, shall never fail from thy mouth, nor from the mouth of thy seed, for the Lord has spoken it, henceforth and for ever."}}]}, {"c": 60, "verses": [{"v": 1, "ref": "60:1", "o": "ק֥וּמִי א֖וֹרִי כִּ֣י בָ֣א אוֹרֵ֑/ךְ וּ/כְב֥וֹד יְהוָ֖ה עָלַ֥יִ/ךְ זָרָֽח", "en": {"kjv": "Arise, shine; for thy light is come, and the glory of the Lord is risen upon thee.", "web": "“Arise, shine; for your light has come, and Yahweh’s glory is risen on you.", "bsb": "Arise, shine, for your light has come, and the glory of the LORD rises upon you.", "asv": "Arise, shine; for thy light is come, and the glory of Jehovah is risen upon thee.", "ylt": "Arise, be bright, for come hath thy light, And the honour of Jehovah hath risen on thee.", "dra": "Arise, be enlightened, O Jerusalem: for thy light is come, and the glory of the Lord is risen upon thee.", "bbe": "Up! let your face be bright, for your light has come, and the glory of the Lord is shining on you.", "geneva": "Arise, O Ierusalem: be bright, for thy light is come, and the glorie of the Lord is risen vpon thee.", "wycliffe": "Rise thou, Jerusalem, be thou liytned, for thi liyt is comun, and the glorie of the Lord is risun on thee.", "rotherham": "Arise—shine, For thy light, hath come,—And, the glory of Yahweh, on thee, hath beamed;", "darby": "Arise, shine! for thy light is come, and the glory of Jehovah is risen upon thee.", "twenty": "", "jps": "Arise, shine, for thy light is come, and the glory of HaShem is risen upon thee.", "acv": "Arise, shine, for thy light has come, and the glory of Jehovah has risen upon thee.", "anderson": "", "haweis": "", "noyes": "Arise, shine! for thy light is come, And the glory of Jehovah is risen upon thee.", "webster": "Arise, shine; for thy light is come, and the glory of the LORD is risen upon thee.", "vulgate": "surge inluminare quia venit lumen tuum et gloria Domini super te orta est;", "brenton": "Be enlightened, be enlightened, O Jerusalem, for thy light is come, and the glory of the Lord is risen upon thee."}}, {"v": 2, "ref": "60:2", "o": "כִּֽי הִנֵּ֤ה הַ/חֹ֨שֶׁךְ֙ יְכַסֶּה אֶ֔רֶץ וַ/עֲרָפֶ֖ל לְאֻמִּ֑ים וְ/עָלַ֨יִ/ךְ֙ יִזְרַ֣ח יְהוָ֔ה וּ/כְבוֹד֖/וֹ עָלַ֥יִ/ךְ יֵרָאֶֽה", "en": {"kjv": "For, behold, the darkness shall cover the earth, and gross darkness the people: but the Lord shall arise upon thee, and his glory shall be seen upon thee.", "web": "For, behold, darkness shall cover the earth, and gross darkness the peoples; but Yahweh will arise on you, and his glory shall be seen on you.", "bsb": "For behold, darkness covers the earth, and thick darkness is over the peoples; but the LORD will rise upon you, and His glory will appear over you.", "asv": "For, behold, darkness shall cover the earth, and gross darkness the peoples; but Jehovah will arise upon thee, and his glory shall be seen upon thee.", "ylt": "For, lo, the darkness doth cover the earth, And thick darkness the peoples, And on thee rise doth Jehovah, And His honour on thee is seen.", "dra": "For behold darkness shall cover the earth, and a mist the people: but the Lord shall arise upon thee, and his glory shall be seen upon thee.", "bbe": "For truly, the earth will be dark, and the peoples veiled in blackest night; but the Lord will be shining on you, and his glory will be seen among you.", "geneva": "For beholde, darkenesse shall couer the earth, and grosse darkenesse the people: but the Lord shall arise vpon thee, and his glory shall be seene vpon thee.", "wycliffe": "For lo! derknessis schulen hile the erthe, and myist schal hile puplis; but the Lord schal rise on thee, and his glorie schal be seyn in thee.", "rotherham": "For lo! darkness, covereth the earth, And, deep gloom the peoples,—But, on thee, beameth Yahweh, And, his glory, on thee is seen.", "darby": "For behold, darkness shall cover the earth, and gross darkness the peoples; but Jehovah will arise upon thee, and his glory shall be seen on thee.", "twenty": "", "jps": "For, behold, darkness shall cover the earth, and gross darkness the peoples; but upon thee HaShem will arise, and His glory shall be seen upon thee.", "acv": "For, behold, darkness shall cover the earth, and gross darkness the peoples. But Jehovah will arise upon thee, and his glory shall be seen upon thee.", "anderson": "", "haweis": "", "noyes": "For, behold, darkness shall cover the earth, And gross darkness the nations; But upon thee shall Jehovah arise, And his glory shall be seen upon thee.", "webster": "For behold, the darkness shall cover the earth, and gross darkness the people: but the LORD will arise upon thee, and his glory will be seen upon thee.", "vulgate": "quia ecce tenebrae operient terram et caligo populos super te autem orietur Dominus et gloria eius in te videbitur;", "brenton": "Behold, darkness shall cover the earth, and there shall be gross darkness on the nations: but the Lord shall appear upon thee, and his glory shall be seen upon thee."}}, {"v": 3, "ref": "60:3", "o": "וְ/הָלְכ֥וּ גוֹיִ֖ם לְ/אוֹרֵ֑/ךְ וּ/מְלָכִ֖ים לְ/נֹ֥גַהּ זַרְחֵֽ/ךְ", "en": {"kjv": "And the Gentiles shall come to thy light, and kings to the brightness of thy rising.", "web": "Nations shall come to your light, and kings to the brightness of your rising.", "bsb": "Nations will come to your light, and kings to the brightness of your dawn.", "asv": "And nations shall come to thy light, and kings to the brightness of thy rising.", "ylt": "And come have nations to thy light, And kings to the brightness of thy rising.", "dra": "And the Gentiles shall walk in thy light, and kings in the brightness of thy rising.", "bbe": "And nations will come to your light, and kings to your bright dawn.", "geneva": "And the Gentiles shall walke in thy light, and Kings at the brightnesse of thy rising vp.", "wycliffe": "And hethene men schulen go in thi liyt, and kyngis `schulen go in the schynyng of thi risyng.", "rotherham": "So shall nations come to thy light, And kings to the brightness of thy dawning.", "darby": "And the nations shall walk by thy light, and kings by the brightness of thy rising.", "twenty": "", "jps": "And nations shall walk at thy light, and kings at the brightness of thy rising.", "acv": "And nations shall come to thy light, and kings to the brightness of thy rising.", "anderson": "", "haweis": "", "noyes": "Nations shall come to thy light, And kings to the brightness that riseth upon thee.", "webster": "And the Gentiles shall come to thy light, and kings to the brightness of thy rising.", "vulgate": "et ambulabunt gentes in lumine tuo et reges in splendore ortus tui;", "brenton": "And kings shall walk in thy light, and nations in thy brightness."}}, {"v": 4, "ref": "60:4", "o": "שְׂאִֽי סָבִ֤יב עֵינַ֨יִ/ךְ֙ וּ/רְאִ֔י כֻּלָּ֖/ם נִקְבְּצ֣וּ בָֽאוּ לָ֑/ךְ בָּנַ֨יִ/ךְ֙ מֵ/רָח֣וֹק יָבֹ֔אוּ וּ/בְנֹתַ֖יִ/ךְ עַל צַ֥ד תֵּאָמַֽנָה", "en": {"kjv": "Lift up thine eyes round about, and see: all they gather themselves together, they come to thee: thy sons shall come from far, and thy daughters shall be nursed at thy side.", "web": "“Lift up your eyes all around, and see: they all gather themselves together, they come to you; your sons shall come from far, and your daughters shall be carried in the arms.", "bsb": "Lift up your eyes and look around: They all gather and come to you; your sons will come from afar, and your daughters will be carried on the arm.", "asv": "Lift up thine eyes round about, and see: they all gather themselves together, they come to thee; thy sons shall come from far, and thy daughters shall be carried in the arms.", "ylt": "Lift up round about thine eyes and see, All of them have been gathered, they have come to thee, Thy sons from afar do come, And thy daughters on the side are supported.", "dra": "Lift up thy eyes round about, and see: all these are gathered together, they are come to thee: thy sons shall come from afar, and thy daughters shall rise up at thy side.", "bbe": "Let your eyes be lifted up, and see: they are all coming together to you: your sons will come from far, and your daughters taken with loving care.", "geneva": "Lift vp thine eyes round about, and beholde: all these are gathered, and come to thee: thy sonnes shall come from farre, and thy daughters shalbe nourished at thy side.", "wycliffe": "Reise thin iyen in cumpas, and se; alle these men ben gaderid togidere, thei ben comun to thee; thi sones schulen come fro fer, and thi douytris schulen rise fro the side.", "rotherham": "Lift up—round about—thine eyes and see, They all, have gathered themselves together—have come to thee,—Thy sons, from afar shall come, And thy daughters, on the side, shall be carried.", "darby": "Lift up thine eyes round about, and see: all they gather themselves together, they come to thee: thy sons come from afar, and thy daughters are carried upon the side.", "twenty": "", "jps": "Lift Up thine eyes round about, and see: they all are gathered together, and come to thee; thy sons come from far, and thy daughters are borne on the side.", "acv": "Lift up thine eyes round about, and see. They all gather themselves together. They come to thee. Thy sons shall come from far, and thy daughters shall be carried in the arms.", "anderson": "", "haweis": "", "noyes": "Lift up thine eyes round about and see! They all gather themselves together, and come to thee; Thy sons come from afar, And thy daughters are carried at thy side.", "webster": "Lift up thy eyes around, and see: all they assemble themselves, they come to thee: thy sons shall come from far, and thy daughters shall be nursed at [thy] side.", "vulgate": "leva in circuitu oculos tuos et vide omnes isti congregati sunt venerunt tibi filii tui de longe venient et filiae tuae in latere sugent;", "brenton": "Lift up thine eyes round about, and behold thy children gathered: all thy sons have come from far, and thy daughters shall be borne on men's shoulders."}}, {"v": 5, "ref": "60:5", "o": "אָ֤ז תִּרְאִי֙ וְ/נָהַ֔רְתְּ וּ/פָחַ֥ד וְ/רָחַ֖ב לְבָבֵ֑/ךְ כִּֽי יֵהָפֵ֤ךְ עָלַ֨יִ/ךְ֙ הֲמ֣וֹן יָ֔ם חֵ֥יל גּוֹיִ֖ם יָבֹ֥אוּ לָֽ/ךְ", "en": {"kjv": "Then thou shalt see, and flow together, and thine heart shall fear, and be enlarged; because the abundance of the sea shall be converted unto thee, the forces of the Gentiles shall come unto thee.", "web": "Then you shall see and be radiant, and your heart shall thrill and be enlarged; because the abundance of the sea shall be turned to you, the wealth of the nations shall come to you.", "bsb": "Then you will look and be radiant, and your heart will tremble and swell with joy, because the riches of the sea will be brought to you, and the wealth of the nations will come to you.", "asv": "Then thou shalt see and be radiant, and thy heart shall thrill and be enlarged; because the abundance of the sea shall be turned unto thee, the wealth of the nations shall come unto thee.", "ylt": "Then thou seest, and hast become bright, And thine heart hath been afraid and enlarged, For turn unto thee doth the multitude of the sea, The forces of nations do come to thee.", "dra": "Then shalt thou see, and abound, and thy heart shall wonder and be enlarged, when the multitude of the sea shall be converted to thee, the strength of the Gentiles shall come to thee.", "bbe": "Then you will see, and be bright with joy, and your heart will be shaking with increase of delight: for the produce of the sea will be turned to you, the wealth of the nations will come to you.", "geneva": "Then thou shalt see and shine: thine heart shall be astonied and enlarged, because the multitude of the sea shalbe conuerted vnto thee, and the riches of the Gentiles shall come vnto thee.", "wycliffe": "Thanne thou schalt se, and schalt flowe; and thin herte schal wondre, and schal be alargid, whanne the multitude of the see is conuertid to thee, the strengthe of hethene men is comun to thee;", "rotherham": "Then, shalt thou see and be radiant, And thy heart, shall throb and be enlarged,—For there shall be turned upon thee the fulness of the sea, The riches of the nations, shall come unto thee;", "darby": "Then thou shalt see, and shalt be brightened, and thy heart shall throb, and be enlarged; for the abundance of the sea shall be turned unto thee, the wealth of the nations shall come unto thee.", "twenty": "", "jps": "Then thou shalt see and be radiant, and thy heart shall throb and be enlarged; because the abundance of the sea shall be turned unto thee, the wealth of the nations shall come unto thee.", "acv": "Then thou shall see and be radiant, and thy heart shall thrill and be enlarged, because the abundance of the sea shall be turned to thee. The wealth of the nations shall come to thee.", "anderson": "", "haweis": "", "noyes": "Then shalt thou see, and be bright with joy; Thy heart shall throb, and swell with delight, When the riches of the sea shall be turned toward thee, And the wealth of the nations shall come to thee.", "webster": "Then thou shalt see, and flow together, and thy heart shall fear, and be enlarged; because the abundance of the sea shall be converted to thee, the forces of the Gentiles shall come to thee.", "vulgate": "tunc videbis et afflues et mirabitur et dilatabitur cor tuum quando conversa fuerit ad te multitudo maris fortitudo gentium venerit tibi;", "brenton": "Then shalt thou see, and fear, and be amazed in thine heart; for the wealth of the sea shall come round to thee, and of nations and peoples; and herds of camels shall come to thee,"}}, {"v": 6, "ref": "60:6", "o": "שִֽׁפְעַ֨ת גְּמַלִּ֜ים תְּכַסֵּ֗/ךְ בִּכְרֵ֤י מִדְיָן֙ וְ/עֵיפָ֔ה כֻּלָּ֖/ם מִ/שְּׁבָ֣א יָבֹ֑אוּ זָהָ֤ב וּ/לְבוֹנָה֙ יִשָּׂ֔אוּ וּ/תְהִלֹּ֥ת יְהוָ֖ה יְבַשֵּֽׂרוּ", "en": {"kjv": "The multitude of camels shall cover thee, the dromedaries of Midian and Ephah; all they from Sheba shall come: they shall bring gold and incense; and they shall shew forth the praises of the Lord.", "web": "The multitude of camels shall cover you, the dromedaries of Midian and Ephah; all they from Sheba shall come; they shall bring gold and frankincense, and shall proclaim the praises of Yahweh.", "bsb": "Caravans of camels will cover your land, young camels of Midian and Ephah, and all from Sheba will come, bearing gold and frankincense and proclaiming the praises of the LORD.", "asv": "The multitude of camels shall cover thee, the dromedaries of Midian and Ephah; all they from Sheba shall come; they shall bring gold and frankincense, and shall proclaim the praises of Jehovah.", "ylt": "A company of camels covereth thee, Dromedaries of Midian and Ephah, All of them from Sheba do come, Gold and frankincense they bear, And of the praises of Jehovah they proclaim the tidings.", "dra": "The multitude of camels shall cover thee, the dromedaries of Madian and Epha: all they from Saba shall come, bringing gold and frankincense: and shewing forth praise to the Lord.", "bbe": "You will be full of camel-trains, even the young camels of Midian and Ephah; all from Sheba will come, with gold and spices, giving word of the great acts of the Lord.", "geneva": "The multitude of camels shall couer thee: and the dromedaries of Midian and of Ephah: all they of Sheba shall come: they shall bring golde and incense, and shewe foorth the prayses of the Lord.", "wycliffe": "the flowyng of camels schal hile thee, the lederis of dromedis of Madian and of Effa; alle men of Saba schulen come, bryngynge gold and encense, and tellynge heriyng to the Lord.", "rotherham": "The multitude of camels, shall cover thee The young camels of Midian and Ephah, All they of Sheba, shall come,—Gold and frankincense, shall they bring, And, the praises of Yahweh, shall they joyfully tell:", "darby": "A multitude of camels shall cover thee, young camels of Midian and Ephah; all they from Sheba shall come: they shall bring gold and incense; and they shall publish the praises of Jehovah.", "twenty": "", "jps": "The caravan of camels shall cover thee, and of the young camels of Midian and Ephah, all coming from Sheba; they shall bring gold and incense, and shall proclaim the praises of HaShem.", "acv": "The multitude of camels shall cover thee. The dromedaries of Midian and Ephah, all those from Sheba shall come. They shall bring gold and frankincense, and shall proclaim the praises of Jehovah.", "anderson": "", "haweis": "", "noyes": "A multitude of camels shall cover thee, Dromedaries from Midian and Ephah; From Sheba shall they all come. Gold and frankincense shall they bring, And proclaim the praises of Jehovah.", "webster": "The multitude of camels shall cover thee, the dromedaries of Midian and Ephah; all they from Sheba shall come: they shall bring gold and incense; and they shall show forth the praises of the LORD.", "vulgate": "inundatio camelorum operiet te dromedariae Madian et Efa omnes de Saba venient aurum et tus deferentes et laudem Domino adnuntiantes;", "brenton": "and the camels of Madiam and Gaepha shall cover thee: all from Saba shall come bearing gold, and shall bring frankincense, and they shall publish the salvation of the Lord."}}, {"v": 7, "ref": "60:7", "o": "כָּל צֹ֤אן קֵדָר֙ יִקָּ֣בְצוּ לָ֔/ךְ אֵילֵ֥י נְבָי֖וֹת יְשָׁרְת֑וּ/נֶךְ יַעֲל֤וּ עַל רָצוֹן֙ מִזְבְּחִ֔/י וּ/בֵ֥ית תִּפְאַרְתִּ֖/י אֲפָאֵֽר", "en": {"kjv": "All the flocks of Kedar shall be gathered together unto thee, the rams of Nebaioth shall minister unto thee: they shall come up with acceptance on mine altar, and I will glorify the house of my glory.", "web": "All the flocks of Kedar shall be gathered together to you, the rams of Nebaioth shall minister to you; they shall come up with acceptance on my altar; and I will glorify the house of my glory.", "bsb": "All the flocks of Kedar will be gathered to you; the rams of Nebaioth will serve you and go up on My altar with acceptance; I will adorn My glorious house.", "asv": "All the flocks of Kedar shall be gathered together unto thee, the rams of Nebaioth shall minister unto thee; they shall come up with acceptance on mine altar; and I will glorify the house of my glory.", "ylt": "All the flock of Kedar are gathered to thee, The rams of Nebaioth do serve thee, They ascend for acceptance Mine altar, And the house of My beauty I beautify.", "dra": "All the flocks of Cedar shall be gathered together unto thee, the rams of Nabaioth shall minister to thee: they shall be offered upon my acceptable altar, and I will glorify the house of my majesty.", "bbe": "All the flocks of Kedar will come together to you, the sheep of Nebaioth will be ready for your need; they will be pleasing offerings on my altar, and my house of prayer will be beautiful.", "geneva": "All the sheepe of Kedar shall be gathered vnto thee: the rammes of Nebaioth shall serue thee: they shall come vp to bee accepted vpon mine altar: and I will beautifie the house of my glorie.", "wycliffe": "Ech scheep of Cedar schal be gaderid to thee, the rammes of Nabaioth schulen mynystre to thee; thei schulen be offrid on myn acceptable auter, and Y schal glorifie the hous of my maieste.", "rotherham": "All the flocks of Kedar, shall be gathered unto thee, The rams of Nebaioth, shall wait upon thee,—They shall come up, with acceptance, on mine altar, And my beautiful house, will I adorn.", "darby": "All the flocks of Kedar shall be gathered unto thee, the rams of Nebaioth shall serve thee: they shall come up with acceptance on mine altar, and I will beautify the house of my magnificence.", "twenty": "", "jps": "All the flocks of Kedar shall be gathered together unto thee, the rams of Nebaioth shall minister unto thee; they shall come up with acceptance on Mine altar, and I will glorify My glorious house.", "acv": "All the flocks of Kedar shall be gathered together to thee. The rams of Nebaioth shall minister to thee. They shall come up with acceptance on my altar, and I will glorify the house of my glory.", "anderson": "", "haweis": "", "noyes": "All the flocks of Kedar shall be gathered to thee, And the rams of Nebaioth shall minister to thee; They shall ascend mine altar, an acceptable offering, And my glorious house I will adorn.", "webster": "All the flocks of Kedar shall be gathered to thee, the rams of Nebaioth shall minister to thee: they shall come up with acceptance on my altar, and I will glorify the house of my glory.", "vulgate": "omne pecus Cedar congregabitur tibi arietes Nabaioth ministrabunt tibi offerentur super placabili altari meo et domum maiestatis meae glorificabo;", "brenton": "And all the flocks of Kedar shall be gathered, and the rams of Nabaeoth shall come; and acceptable sacrifices shall be offered on my altar, and my house of prayer shall be glorified."}}, {"v": 8, "ref": "60:8", "o": "מִי אֵ֖לֶּה כָּ/עָ֣ב תְּעוּפֶ֑ינָה וְ/כַ/יּוֹנִ֖ים אֶל אֲרֻבֹּתֵי/הֶֽם", "en": {"kjv": "Who are these that fly as a cloud, and as the doves to their windows?", "web": "“Who are these who fly as a cloud, and as the doves to their windows?", "bsb": "Who are these who fly like clouds, like doves to their shelters?", "asv": "Who are these that fly as a cloud, and as the doves to their windows?", "ylt": "Who are these--as a thick cloud they fly, And as doves unto their windows?", "dra": "Who are these, that fly as clouds, and as doves to their windows?", "bbe": "Who are these coming like a cloud, like a flight of doves to their windows?", "geneva": "Who are these that flee like a cloude, and as the doues to their windowes?", "wycliffe": "Who ben these, that fleen as cloudis, and as culueris at her wyndowis?", "rotherham": "Who are these that, As a cloud, do fly? and, As doves to their cotes?", "darby": "Who are these that come flying as a cloud, and as doves to their dove-cotes?", "twenty": "", "jps": "Who are these that fly as a cloud, and as the doves to their cotes?", "acv": "Who are these that fly as a cloud, and as the doves to their windows?", "anderson": "", "haweis": "", "noyes": "Who are these that fly like clouds, And like doves to their habitations?", "webster": "Who [are] these [that] fly as a cloud, and as doves to their windows?", "vulgate": "qui sunt isti qui ut nubes volant et quasi columbae ad fenestras suas;", "brenton": "Who are these that fly as clouds, and as doves with young ones to me?"}}, {"v": 9, "ref": "60:9", "o": "כִּֽי לִ֣/י אִיִּ֣ים יְקַוּ֗וּ וָ/אֳנִיּ֤וֹת תַּרְשִׁישׁ֙ בָּ/רִ֣אשֹׁנָ֔ה לְ/הָבִ֤יא בָנַ֨יִ/ךְ֙ מֵֽ/רָח֔וֹק כַּסְפָּ֥/ם וּ/זְהָבָ֖/ם אִתָּ֑/ם לְ/שֵׁם֙ יְהוָ֣ה אֱלֹהַ֔יִ/ךְ וְ/לִ/קְד֥וֹשׁ יִשְׂרָאֵ֖ל כִּ֥י פֵאֲרָֽ/ךְ", "en": {"kjv": "Surely the isles shall wait for me, and the ships of Tarshish first, to bring thy sons from far, their silver and their gold with them, unto the name of the Lord thy God, and to the Holy One of Israel, because he hath glorified thee.", "web": "Surely the islands shall wait for me, and the ships of Tarshish first, to bring your sons from far, their silver and their gold with them, for the name of Yahweh your God, and for the Holy One of Israel, because he has glorified you.", "bsb": "Surely the islands will wait for Me, with the ships of Tarshish in the lead, to bring your children from afar, with their silver and gold, to the honor of the LORD your God, the Holy One of Israel, for He has glorified you.", "asv": "Surely the isles shall wait for me, and the ships of Tarshish first, to bring thy sons from far, their silver and their gold with them, for the name of Jehovah thy God, and for the Holy One of Israel, because he hath glorified thee.", "ylt": "Surely for Me isles do wait, And ships of Tarshish first, To bring thy sons from afar, Their silver and their gold with them, To the name of Jehovah thy God, And to the Holy One of Israel, Because He hath beautified thee.", "dra": "For, the islands wait for me, and the ships of the sea in the beginning: that I may bring thy sons from afar: their silver, and their gold with them, to the name of the Lord thy God, and to the Holy One of Israel, because he hath glorified thee.", "bbe": "Vessels of the sea-lands are waiting for me, and the ships of Tarshish first, so that your sons may come from far, and their silver and gold with them, to the place of the name of the Lord your God, and to the Holy One of Israel, because he has made you beautiful.", "geneva": "Surely the yles shall waite for mee, and the shippes of Tarshish, as at the beginning, that they may bring thy sonnes from farre, and their siluer, and their golde with them, vnto the Name of the Lord thy God, and to the Holy one of Israel, because he hath glorified thee.", "wycliffe": "Forsothe ilis abiden me, and the schippis of the see in the bigynnyng; that Y brynge thi sones fro fer, the siluer of hem, and the gold of hem is with hem, to the name of thi Lord God, and to the hooli of Israel; for he schal glorifie thee.", "rotherham": "Surely for me, shall, Coastlands, wait, And the ships of Tarshish first, To bring in thy sons, from far, Their silver and their gold with them,—Unto the name of Yahweh, thy God, And unto the Holy One of Israel Because he hath adorned thee.", "darby": "For the isles shall await me, and the ships of Tarshish first, to bring thy sons from afar, their silver and their gold with them, unto the name of Jehovah thyGod, and to the Holy One of Israel, for he hath glorified thee.", "twenty": "", "jps": "Surely the isles shall wait for Me, and the ships of Tarshish first, to bring thy sons from far, their silver and their gold with them, for the name of HaShem thy G-d, and for the Holy One of Israel, because He hath glorified thee.", "acv": "Surely the isles shall wait for me, and the ships of Tarshish first, to bring thy sons from far, their silver and their gold with them, for the name of Jehovah thy God, and for the Holy One of Israel, because he has glorified thee.", "anderson": "", "haweis": "", "noyes": "Behold, the distant coasts shall wait for me, And the ships of Tarshish among the first, To bring thy sons from afar, And their silver and their gold with them, Because of the name of Jehovah thy God, Of the Holy One of Israel, for he glorifieth thee.", "webster": "Surely the isles shall wait for me, and the ships of Tarshish first, to bring thy sons from far, their silver and their gold with them, to the name of the LORD thy God, and to the Holy One of Israel, because he hath glorified thee.", "vulgate": "me enim insulae expectant et naves maris in principio ut adducam filios tuos de longe argentum eorum et aurum eorum cum eis nomini Domini Dei tui et Sancto Israhel quia glorificavit te;", "brenton": "The isles have waited for me, and the ships of Tharsis among the first, to bring thy children from afar, and their silver and their gold with them, and that for the sake of the holy name of the Lord, and because the Holy One of Israel is glorified."}}, {"v": 10, "ref": "60:10", "o": "וּ/בָנ֤וּ בְנֵֽי נֵכָר֙ חֹמֹתַ֔יִ/ךְ וּ/מַלְכֵי/הֶ֖ם יְשָׁרְת֑וּ/נֶךְ כִּ֤י בְ/קִצְפִּ/י֙ הִכִּיתִ֔י/ךְ וּ/בִ/רְצוֹנִ֖/י רִֽחַמְתִּֽי/ךְ", "en": {"kjv": "And the sons of strangers shall build up thy walls, and their kings shall minister unto thee: for in my wrath I smote thee, but in my favour have I had mercy on thee.", "web": "“Foreigners shall build up your walls, and their kings shall minister to you: for in my wrath I struck you, but in my favor have I had mercy on you.", "bsb": "Foreigners will rebuild your walls, and their kings will serve you. Although I struck you in anger, yet in favor I will show you mercy.", "asv": "And foreigners shall build up thy walls, and their kings shall minister unto thee: for in my wrath I smote thee, but in my favor have I had mercy on thee.", "ylt": "And sons of a stranger have built thy walls, And their kings do serve thee, For in My wrath I have smitten thee, And in My good pleasure I have pitied thee.", "dra": "And the children of strangers shall build up thy walls, and their kings shall minister to thee: for in my wrath have I struck thee, and in my reconciliation have I had mercy upon thee.", "bbe": "And men from strange countries will be building up your walls, and their kings will be your servants: for in my wrath I sent punishment on you, but in my grace I have had mercy on you.", "geneva": "And the sonnes of strangers shall builde vp thy walles, and their Kings shall minister vnto thee: for in my wrath I smote thee, but in my mercie I had compassion on thee.", "wycliffe": "And the sones of pilgrymes schulen bilde thi wallis, and the kyngis of hem schulen mynystre to thee. For Y smoot thee in myn indignacioun, and in my recounselyng Y hadde merci on thee.", "rotherham": "So shall the sons of the foreigner, build thy walls, And their kings, shall wait upon thee,—For in my vexation, I smote thee, But in my favour, have I had compassion upon thee.", "darby": "And the sons of the alien shall build up thy walls, and their kings shall minister unto thee. For in my wrath I smote thee, but in my favour have I had mercy on thee.", "twenty": "", "jps": "And aliens shall build up thy walls, And their kings shall minister unto thee; for in My wrath I smote thee, but in My favour have I had compassion on thee.", "acv": "And foreigners shall build up thy walls, and their kings shall minister to thee. For in my wrath I smote thee, but in my favor I have had mercy on thee.", "anderson": "", "haweis": "", "noyes": "The sons of the stranger shall build up thy walls, And their kings shall minister to thee; For in my wrath I smote thee, But in my mercy will I have pity upon thee.", "webster": "And the sons of strangers shall build up thy walls, and their kings shall minister to thee: for in my wrath I smote thee, but in my favor have I had mercy on thee.", "vulgate": "et aedificabunt filii peregrinorum muros tuos et reges eorum ministrabunt tibi in indignatione enim mea percussi te et in reconciliatione mea misertus sum tui;", "brenton": "And strangers shall build thy walls, and their kings shall wait upon thee: for by reason of my wrath I smote thee, and by reason of mercy I loved thee."}}, {"v": 11, "ref": "60:11", "o": "וּ/פִתְּח֨וּ שְׁעָרַ֧יִ/ךְ תָּמִ֛יד יוֹמָ֥ם וָ/לַ֖יְלָה לֹ֣א יִסָּגֵ֑רוּ לְ/הָבִ֤יא אֵלַ֨יִ/ךְ֙ חֵ֣יל גּוֹיִ֔ם וּ/מַלְכֵי/הֶ֖ם נְהוּגִֽים", "en": {"kjv": "Therefore thy gates shall be open continually; they shall not be shut day nor night; that men may bring unto thee the forces of the Gentiles, and that their kings may be brought.", "web": "Your gates also shall be open continually; they shall not be shut day nor night; that men may bring to you the wealth of the nations, and their kings led captive.", "bsb": "Your gates will always stand open; they will never be shut, day or night, so that the wealth of the nations may be brought into you, with their kings being led in procession.", "asv": "Thy gates also shall be open continually; they shall not be shut day nor night; that men may bring unto thee the wealth of the nations, and their kings led captive.", "ylt": "And opened have thy gates continually, By day and by night they are not shut, To bring unto thee the force of nations, Even their kings are led.", "dra": "And thy gates shall be open continually: they shall not be shut day nor night, that the strength of the Gentiles may be brought to thee, and their kings may be brought.", "bbe": "Your doors will be open at all times; they will not be shut day or night; so that men may come into you with the wealth of the nations, with their kings at their head.", "geneva": "Therefore thy gates shalbe open continually: neither day nor night shall they be shutte, that men may bring vnto thee the riches of the Gentiles, and that their Kings may be brought.", "wycliffe": "And thi yatis schulen be openyd contynueli, day and niyt tho schulen not be closid; that the strengthe of hethene men be brouyt to thee, and the kyngis of hem be brouyt.", "rotherham": "So shall thy gates be open—continually, Neither day nor night, shall they be shut,—That they may bring unto thee the riches of the nations, And their kings, be led.", "darby": "And thy gates shall stand open continually: (they shall not be shut day nor night,) that the wealth of the nations may be brought unto thee, and that their kings may be led [to thee].", "twenty": "", "jps": "Thy gates also shall be open continually, day and night, they shall not be shut; that men may bring unto thee the wealth of the nations, and their kings in procession.", "acv": "Thy gates also shall be open continually. They shall not be shut day nor night, that men may bring to thee the wealth of the nations, and their kings led captive.", "anderson": "", "haweis": "", "noyes": "Thy gates shall be open continually; They shall not be shut by day or by night, That the treasures of the nations may be brought to thee, And that their kings may come with their retinues.", "webster": "Therefore thy gates shall be open continually; they shall not be shut day nor night; that [men] may bring to thee the forces of the Gentiles, and [that] their kings [may be] brought.", "vulgate": "et aperientur portae tuae iugiter die et nocte non claudentur ut adferatur ad te fortitudo gentium et reges earum adducantur;", "brenton": "And thy gates shall be opened continually; they shall not be shut day nor night; to bring in to thee the power of the Gentiles, and their kings as captives."}}, {"v": 12, "ref": "60:12", "o": "כִּֽי הַ/גּ֧וֹי וְ/הַ/מַּמְלָכָ֛ה אֲשֶׁ֥ר לֹא יַעַבְד֖וּ/ךְ יֹאבֵ֑דוּ וְ/הַ/גּוֹיִ֖ם חָרֹ֥ב יֶחֱרָֽבוּ", "en": {"kjv": "For the nation and kingdom that will not serve thee shall perish; yea, those nations shall be utterly wasted.", "web": "For that nation and kingdom that will not serve you shall perish; yes, those nations shall be utterly wasted.", "bsb": "For the nation or kingdom that will not serve you will perish; it will be utterly destroyed.", "asv": "For that nation and kingdom that will not serve thee shall perish; yea, those nations shall be utterly wasted.", "ylt": "For the nation and the kingdom that do not serve thee perish, Yea, the nations are utterly wasted.", "dra": "For the nation and the kingdom that will not serve thee, shall perish: and the Gentiles shall be wasted with desolation.", "bbe": "For the nation or kingdom which will not be your servant will come to destruction; such nations will be completely waste.", "geneva": "For the nation and the kingdome, that will not serue thee, shall perish: and those nations shalbe vtterly destroyed.", "wycliffe": "For whi the folk and rewme that serueth not thee, schal perische, and hethene men schulen be distried bi wildirnesse.", "rotherham": "For, the nation and the kingdom that will not serve thee, shall perish,—Yea the nations, shall be utterly wasted.", "darby": "For the nation and the kingdom that will not serve thee shall perish; and those nations shall be utterly wasted.", "twenty": "", "jps": "For that nation and kingdom that will not serve thee shall perish; yea, those nations shall be utterly wasted.", "acv": "For that nation and kingdom that will not serve thee shall perish. Yea, those nations shall be utterly wasted.", "anderson": "", "haweis": "", "noyes": "For that nation and that kingdom Which will not serve thee shall perish; Yea, those nations shall be utterly destroyed.", "webster": "For the nation and kingdom that will not serve thee shall perish; yes, [those] nations shall be utterly wasted.", "vulgate": "gens enim et regnum quod non servierit tibi peribit et gentes solitudine vastabuntur;", "brenton": "For the nations and the kings which will not serve thee shall perish; and those nations shall be made utterly desolate."}}, {"v": 13, "ref": "60:13", "o": "כְּב֤וֹד הַ/לְּבָנוֹן֙ אֵלַ֣יִ/ךְ יָב֔וֹא בְּר֛וֹשׁ תִּדְהָ֥ר וּ/תְאַשּׁ֖וּר יַחְדָּ֑ו לְ/פָאֵר֙ מְק֣וֹם מִקְדָּשִׁ֔/י וּ/מְק֥וֹם רַגְלַ֖/י אֲכַבֵּֽד", "en": {"kjv": "The glory of Lebanon shall come unto thee, the fir tree, the pine tree, and the box together, to beautify the place of my sanctuary; and I will make the place of my feet glorious.", "web": "“The glory of Lebanon shall come to you, the fir tree, the pine, and the box tree together, to beautify the place of my sanctuary; and I will make the place of my feet glorious.", "bsb": "The glory of Lebanon will come to you— its cypress, elm, and boxwood together— to adorn the place of My sanctuary, and I will glorify the place of My feet.", "asv": "The glory of Lebanon shall come unto thee, the fir-tree, the pine, and the box-tree together, to beautify the place of my sanctuary; and I will make the place of my feet glorious.", "ylt": "The honour of Lebanon unto thee doth come, Fir, pine, and box together, To beautify the place of My sanctuary, And the place of My feet I make honourable.", "dra": "The glory of Libanus shall come to thee, the fir tree, and the box tree, and the pine tree together, to beautify the place of my sanctuary: and I will glorify the place of my feet.", "bbe": "The glory of Lebanon will come to you, the cypress, the plane, and the sherbin-tree together, to make my holy place beautiful; and the resting-place of my feet will be full of glory.", "geneva": "The glory of Lebanon shall come vnto thee, the firre tree, the elme and the boxe tree together, to beautifie the place of my Sanctuarie: for I will glorifie the place of my feete.", "wycliffe": "The glorie of the Liban schal come to thee, a fir tre, and box tre, and pyne appil tre togidere, to ourne the place of myn halewyng; and Y schal glorifie the place of my feet.", "rotherham": "The glory of Lebanon, unto thee, shall come, The fir-tree the holm-oak, and the sherbin-cedar, together, To adorn the place of my sanctuary, And the place of my feet, will I make glorious.", "darby": "The glory of Lebanon shall come unto thee, the cypress, pine, and box-tree together, to beautify the place of my sanctuary; and I will make the place of my feet glorious.", "twenty": "", "jps": "The glory of Lebanon shall come unto thee, the cypress, the plane-tree and the larch together; to beautify the place of My sanctuary, and I will make the place of My feet glorious.", "acv": "The glory of Lebanon shall come to thee, the fir tree, the pine, and the box tree together, to beautify the place of my sanctuary. And I will make the place of my feet glorious.", "anderson": "", "haweis": "", "noyes": "The glory of Lebanon shall come to thee, The cypress, the plane-tree, and the larch together, To adorn the place of my sanctuary, That I may make the place where my feet rest glorious.", "webster": "The glory of Lebanon shall come to thee, the fir-tree, the pine-tree, and the box together, to beautify the place of my sanctuary; and I will make the place of my feet glorious.", "vulgate": "gloria Libani ad te veniet abies et buxus et pinus simul ad ornandum locum sanctificationis meae et locum pedum meorum glorificabo;", "brenton": "And the glory of Libanus shall come to thee, with the cypress, and pine, and cedar together, to glorify my holy place."}}, {"v": 14, "ref": "60:14", "o": "וְ/הָלְכ֨וּ אֵלַ֤יִ/ךְ שְׁח֨וֹחַ֙ בְּנֵ֣י מְעַנַּ֔יִ/ךְ וְ/הִֽשְׁתַּחֲו֛וּ עַל כַּפּ֥וֹת רַגְלַ֖יִ/ךְ כָּל מְנַֽאֲצָ֑יִ/ךְ וְ/קָ֤רְאוּ לָ/ךְ֙ עִ֣יר יְהוָ֔ה צִיּ֖וֹן קְד֥וֹשׁ יִשְׂרָאֵֽל", "en": {"kjv": "The sons also of them that afflicted thee shall come bending unto thee; and all they that despised thee shall bow themselves down at the soles of thy feet; and they shall call thee, The city of the Lord, The Zion of the Holy One of Israel.", "web": "The sons of those who afflicted you shall come bending to you; and all those who despised you shall bow themselves down at the soles of your feet; and they shall call you The city of Yahweh, The Zion of the Holy One of Israel.", "bsb": "The sons of your oppressors will come and bow down to you; all who reviled you will fall facedown at your feet and call you the City of the LORD, Zion of the Holy One of Israel.", "asv": "And the sons of them that afflicted thee shall come bending unto thee; and all they that despised thee shall bow themselves down at the soles of thy feet; and they shall call thee The city of Jehovah, The Zion of the Holy One of Israel.", "ylt": "And come unto thee, bowing down, Have sons of those afflicting thee, And bowed themselves to the soles of thy feet Have all despising thee, And they have cried to thee: `City of Jehovah, Zion of the Holy One of Israel.'", "dra": "And the children of them that afflict thee, shall come bowing down to thee, and all that slandered thee shall worship the steps of thy feet, and shall call thee the city of the Lord, the Sion of the Holy One of Israel.", "bbe": "And the sons of those who were cruel to you will come before you with bent heads; and those who made sport of you will go down on their faces at your feet; and you will be named, The Town of the Lord, The Zion of the Holy One of Israel.", "geneva": "The sonnes also of them that afflicted thee, shall come and bowe vnto thee: and all they that despised thee, shall fall downe at the soles of thy feete: and they shall call thee, The citie of the Lord, Zion of the Holy one of Israel.", "wycliffe": "And the sones of hem that maden thee lowe, schulen come lowe to thee, and alle that bacbitiden thee, schulen worschipe the steppis of thi feet; and schulen clepe thee A citee of the Lord of Sion, of the hooli of Israel.", "rotherham": "Then shall come unto thee bending low, The sons of them who had humbled thee, Then shall bow down, unto the soles of thy feet, All they who had despised thee; And they shall call thee—The city of Yahweh, The Zion of the Holy One of Israel.", "darby": "And the children of them that afflicted thee shall come bending unto thee; and all they that despised thee shall bow themselves down at the soles of thy feet; and they shall call thee The city of Jehovah, the Zion of the Holy One of Israel.", "twenty": "", "jps": "And the sons of them that afflicted thee shall come bending unto thee, and all they that despised thee shall bow down at the soles of thy feet; and they shall call thee The city of HaShem, the Zion of the Holy One of Israel.", "acv": "And the sons of those who afflicted thee shall come bending to thee. And all those who despised thee shall bow themselves down at the soles of thy feet. And they shall call thee The city of Jehovah, The Zion of the Holy One of Israel.", "anderson": "", "haweis": "", "noyes": "The sons of thine oppressors shall come bending before thee; They that despised thee shall fall down at thy feet; And they shall call thee the city of Jehovah, The Zion of the Holy One of Israel.", "webster": "The sons also of them that afflicted thee shall come bending to thee; and all they that despised thee shall bow themselves down at the soles of thy feet; and they shall call thee, The city of the LORD, The Zion of the Holy One of Israel.", "vulgate": "et venient ad te curvi filii eorum qui humiliaverunt te et adorabunt vestigia pedum tuorum omnes qui detrahebant tibi et vocabunt te civitatem Domini Sion Sancti Israhel;", "brenton": "And the sons of them that afflicted thee, and of them that provoked thee, shall come to thee in fear; and thou shalt be called Sion, the city of the Holy One of Israel."}}, {"v": 15, "ref": "60:15", "o": "תַּ֧חַת הֱיוֹתֵ֛/ךְ עֲזוּבָ֥ה וּ/שְׂנוּאָ֖ה וְ/אֵ֣ין עוֹבֵ֑ר וְ/שַׂמְתִּי/ךְ֙ לִ/גְא֣וֹן עוֹלָ֔ם מְשׂ֖וֹשׂ דּ֥וֹר וָ/דֽוֹר", "en": {"kjv": "Whereas thou hast been forsaken and hated, so that no man went through thee, I will make thee an eternal excellency, a joy of many generations.", "web": "“Whereas you have been forsaken and hated, so that no man passed through you, I will make you an eternal excellency, a joy of many generations.", "bsb": "Whereas you have been forsaken and despised, with no one passing through, I will make you an everlasting pride, a joy from age to age.", "asv": "Whereas thou hast been forsaken and hated, so that no man passed through thee, I will make thee an eternal excellency, a joy of many generations.", "ylt": "Instead of thy being forsaken and hated, And none passing through, I have made thee for an excellency age-during, A joy of generation and generation.", "dra": "Because thou wast forsaken, and hated, and there was none that passed through thee, I will make thee to be an everlasting glory, a joy unto generation and generation:", "bbe": "And though you were turned away from, and hated, and had no helper, I will make you a pride for ever, a joy from generation to generation.", "geneva": "Where as thou hast bene forsaken and hated: so that no man went by thee, I will make thee an eternall glorie, and a ioye from generation to generation.", "wycliffe": "For that that thou were forsakun, and hatid, and noon was that passide bi thee, Y schal sette thee in to pryde of worldis, ioie in generacioun and in to generacioun.", "rotherham": "Instead of thy being forsaken and hated so that none used to pass through thee, I will make of thee—An excellency age-abiding, The joy of generation after generation.", "darby": "Instead of thy being forsaken and hated, so that no one went through [thee], I will make thee an eternal excellency, a joy from generation to generation.", "twenty": "", "jps": "Whereas thou hast been forsaken and hated, so that no man passed through thee, I will make thee an eternal excellency, a joy of many generations.", "acv": "Whereas thou have been forsaken and hated, so that no man passed through thee, I will make thee an eternal excellency, a joy of many generations.", "anderson": "", "haweis": "", "noyes": "Instead of being forsaken and hated, So that no one passed through thee, I will make thee an everlasting glory; The joy of many generations.", "webster": "Whereas thou hast been forsaken and hated, so that no man went through [thee], I will make thee an eternal excellence, a joy of many generations.", "vulgate": "pro eo quod fuisti derelicta et odio habita et non erat qui per te transiret ponam te in superbiam saeculorum gaudium in generationem et generationem;", "brenton": "Because thou has become desolate and hated, and there was no helper, therefore I will make thee a perpetual gladness, a joy of many generations."}}, {"v": 16, "ref": "60:16", "o": "וְ/יָנַקְתְּ֙ חֲלֵ֣ב גּוֹיִ֔ם וְ/שֹׁ֥ד מְלָכִ֖ים תִּינָ֑קִי וְ/יָדַ֗עַתְּ כִּ֣י אֲנִ֤י יְהוָה֙ מֽוֹשִׁיעֵ֔/ךְ וְ/גֹאֲלֵ֖/ךְ אֲבִ֥יר יַעֲקֹֽב", "en": {"kjv": "Thou shalt also suck the milk of the Gentiles, and shalt suck the breast of kings: and thou shalt know that I the Lord am thy Saviour and thy Redeemer, the mighty One of Jacob.", "web": "You shall also drink the milk of the nations, and shall nurse from royal breasts; and you shall know that I, Yahweh, am your Savior, and your Redeemer, the Mighty One of Jacob.", "bsb": "You will drink the milk of nations and nurse at the breasts of royalty; you will know that I, the LORD, am your Savior and your Redeemer, the Mighty One of Jacob.", "asv": "Thou shalt also suck the milk of the nations, and shalt suck the breast of kings; and thou shalt know that I, Jehovah, am thy Saviour, and thy Redeemer, the Mighty One of Jacob.", "ylt": "And thou hast sucked the milk of nations, Yea, the breast of kings thou suckest, And thou hast known that I, Jehovah, Thy Saviour, and Thy Redeemer, Am the Mighty One of Jacob.", "dra": "And thou shalt suck the milk of the Gentiles, and thou shalt be nursed with the breasts of kings: and thou shalt know that I am the Lord thy Saviour, and thy Redeemer, the Mighty One of Jacob.", "bbe": "And you will take the milk of the nations, flowing from the breast of kings; and you will see that I, the Lord, am your saviour, and he who takes up your cause, the Strong One of Jacob.", "geneva": "Thou shalt also sucke ye milke of the Gentiles, and shalt sucke the breastes of Kings: and thou shalt know, that I the Lord am thy Sauiour, and thy Redeemer, the mightie one of Iaakob.", "wycliffe": "And thou schalt souke the mylke of folkis, and thou schalt be soclid with the tete of kyngis; and thou schalt wite that Y am the Lord, sauynge thee, and thin ayen biere, the stronge of Jacob.", "rotherham": "And thou shalt derive sweet nourishment from the nations, Yea on the bounty of kings, shalt thou be sustained,—So shalt thou know—That, I, Yahweh, am thy Saviour, and That, thy Redeemer, is the Mighty One of Jacob.", "darby": "And thou shalt suck the milk of the nations, and shalt suck the breast of kings; and thou shalt know that I, Jehovah, [am] thy Saviour and thy Redeemer, the Mighty One of Jacob.", "twenty": "", "jps": "Thou shalt also suck the milk of the nations, and shalt suck the breast of kings; and thou shalt know that I HaShem am thy Saviour, and I, the Mighty One of Jacob, thy Redeemer.", "acv": "Thou shall also suck the milk of the nations, and shall suck the breast of kings. And thou shall know that I, Jehovah, am thy Savior, and thy Redeemer, the Mighty One of Jacob.", "anderson": "", "haweis": "", "noyes": "Thou shalt also suck the milk of the nations, And be nursed from the breast of kings; And thou shalt know that I, Jehovah, am thy saviour, That thy redeemer is the Mighty One of Jacob.", "webster": "Thou shalt also suck the milk of the Gentiles, and shalt suck the breast of kings: and thou shalt know that I the LORD [am] thy Savior and thy Redeemer, the mighty one of Jacob.", "vulgate": "et suges lac gentium et mamilla regum lactaberis et scies quia ego Dominus salvans te et redemptor tuus Fortis Iacob;", "brenton": "And thou shalt suck the milk of the Gentiles, and shalt eat the wealth of kings: and shalt know that I am the Lord that saves thee and delivers thee, the Holy One of Israel."}}, {"v": 17, "ref": "60:17", "o": "תַּ֣חַת הַ/נְּחֹ֜שֶׁת אָבִ֣יא זָהָ֗ב וְ/תַ֤חַת הַ/בַּרְזֶל֙ אָ֣בִיא כֶ֔סֶף וְ/תַ֤חַת הָֽ/עֵצִים֙ נְחֹ֔שֶׁת וְ/תַ֥חַת הָ/אֲבָנִ֖ים בַּרְזֶ֑ל וְ/שַׂמְתִּ֤י פְקֻדָּתֵ/ךְ֙ שָׁל֔וֹם וְ/נֹגְשַׂ֖יִ/ךְ צְדָקָֽה", "en": {"kjv": "For brass I will bring gold, and for iron I will bring silver, and for wood brass, and for stones iron: I will also make thy officers peace, and thine exactors righteousness.", "web": "For brass I will bring gold, and for iron I will bring silver, and for wood brass, and for stones iron. I will also make your officers peace, and righteousness your ruler.", "bsb": "Instead of bronze I will bring you gold; I will bring silver in place of iron, bronze instead of wood, and iron instead of stones. I will appoint peace as your governor and righteousness as your ruler.", "asv": "For brass I will bring gold, and for iron I will bring silver, and for wood brass, and for stones iron. I will also make thy officers peace, and thine exactors righteousness.", "ylt": "Instead of the brass I bring in gold, And instead of the iron I bring in silver, And instead of the wood brass, And instead of the stone iron, And I have made thy inspection peace, And thy exactors righteousness.", "dra": "For brass I will bring gold, and for iron I will bring silver: and for wood brass, and for stones iron: and I will make thy visitation peace, and thy overseers justice.", "bbe": "In place of brass, I will give gold, and for iron silver, and for wood brass, and for stones iron: and I will make Peace your judge, and Righteousness your overseer.", "geneva": "For brasse will I bring golde, and for yron will I bring siluer, and for wood brasse, and for stones yron. I will also make thy gouernement peace, and thine exactours righteousnesse.", "wycliffe": "For bras Y schal brynge gold, and for irun Y schal brynge siluer; and bras for trees, and yrun for stoonys; and Y schal sette thi visitacioun pees, and thi prelatis riytfulnesse.", "rotherham": "Instead of bronze, I will bring in, gold, and Instead of iron, I will bring in silver, and Instead of wood, bronze, and Instead of stones, iron,—And I will appoint the oversight of thee to Prosperity, And the setting of thy tasks to Righteousness.", "darby": "For bronze I will bring gold, and for iron I will bring silver, and for wood bronze, and for stones iron; and I will make thine officers peace, and thy rulers righteousness.", "twenty": "", "jps": "For brass I will bring gold, and for iron I will bring silver, and for wood brass, and for stones iron; I will also make thy officers peace, and righteousness thy magistrates.", "acv": "For brass I will bring gold, and for iron I will bring silver, and for wood brass, and for stones iron. I will also make thy officers peace, and thine overseers righteousness.", "anderson": "", "haweis": "", "noyes": "Instead of brass will I bring gold; And instead of iron will I bring silver, And instead of wood, brass, And instead of stones, iron; I will make thine officers peace, And thy magistrates righteousness.", "webster": "For brass I will bring gold, and for iron I will bring silver, and for wood brass, and for stones iron: I will also make thy officers peace, and thy exactors righteousness.", "vulgate": "pro aere adferam aurum et pro ferro adferam argentum et pro lignis aes et pro lapidibus ferrum et ponam visitationem tuam pacem et praepositos tuos iustitiam;", "brenton": "And for brass I will bring thee gold, and for iron I will bring thee silver, and instead of wood I will bring thee brass, and instead of stones, iron; and I will make thy princes peaceable, and thine overseers righteous."}}, {"v": 18, "ref": "60:18", "o": "לֹא יִשָּׁמַ֨ע ע֤וֹד חָמָס֙ בְּ/אַרְצֵ֔/ךְ שֹׁ֥ד וָ/שֶׁ֖בֶר בִּ/גְבוּלָ֑יִ/ךְ וְ/קָרָ֤את יְשׁוּעָה֙ חוֹמֹתַ֔יִ/ךְ וּ/שְׁעָרַ֖יִ/ךְ תְּהִלָּֽה", "en": {"kjv": "Violence shall no more be heard in thy land, wasting nor destruction within thy borders; but thou shalt call thy walls Salvation, and thy gates Praise.", "web": "Violence shall no more be heard in your land, desolation nor destruction within your borders; but you shall call your walls Salvation, and your gates Praise.", "bsb": "No longer will violence be heard in your land, nor ruin or destruction within your borders. But you will name your walls Salvation and your gates Praise.", "asv": "Violence shall no more be heard in thy land, desolation nor destruction within thy borders; but thou shalt call thy walls Salvation, and thy gates Praise.", "ylt": "Violence is not heard any more in thy land, Spoiling and destruction in thy borders, And thou hast called `Salvation' thy walls, And thy gates, `Praise.'", "dra": "Iniquity shall no more be heard in thy land, wasting nor destruction in thy borders, and salvation shall possess thy walls, and praise thy gates.", "bbe": "Violent acts will no longer be seen in your land, wasting or destruction in your limits; but your walls will be named, Salvation, and your doors Praise.", "geneva": "Violence shall no more be heard of in thy land, neither desolation, nor destruction within thy borders: but thou shalt call saluation, thy walles, and praise, thy gates.", "wycliffe": "Wickidnesse schal no more be herd in thi lond, nether distriyng and defoulyng in thi coostis; and helthe schal ocupie thi wallis, and heriyng schal ocupie thi yatis.", "rotherham": "Violence, shall no more be heard, in thy land, Wasting nor destruction within thy boundaries,—But thou shalt call Thy walls, Victory, and Thy gates, Praise.", "darby": "Violence shall no more be heard in thy land, wasting nor destruction within thy borders; but thou shalt call thy walls Salvation, and thy gates Praise.", "twenty": "", "jps": "Violence shall no more be heard in thy land, desolation nor destruction within thy borders; but thou shalt call thy walls Salvation, and thy gates Praise.", "acv": "Violence shall no more be heard in thy land, desolation nor destruction within thy borders, but thou shall call thy walls Salvation, and thy gates Praise.", "anderson": "", "haweis": "", "noyes": "Violence shall no more be heard in thy land, Wasting or destruction within thy borders; Thou shalt call thy walls Salvation, And thy gates Praise.", "webster": "Violence shall no more be heard in thy land, wasting nor destruction within thy borders; but thou shalt call thy walls Salvation, and thy gates Praise.", "vulgate": "non audietur ultra iniquitas in terra tua vastitas et contritio in terminis tuis et occupabit salus muros tuos et portas tuas laudatio;", "brenton": "And injustice shall no more be heard in thy land, nor destruction nor misery in thy coasts; but thy walls shall be called Salvation, and thy gates Sculptured Work."}}, {"v": 19, "ref": "60:19", "o": "לֹא יִֽהְיֶה לָּ֨/ךְ ע֤וֹד הַ/שֶּׁ֨מֶשׁ֙ לְ/א֣וֹר יוֹמָ֔ם וּ/לְ/נֹ֕גַהּ הַ/יָּרֵ֖חַ לֹא יָאִ֣יר לָ֑/ךְ וְ/הָיָה לָ֤/ךְ יְהוָה֙ לְ/א֣וֹר עוֹלָ֔ם וֵ/אלֹהַ֖יִ/ךְ לְ/תִפְאַרְתֵּֽ/ךְ", "en": {"kjv": "The sun shall be no more thy light by day; neither for brightness shall the moon give light unto thee: but the Lord shall be unto thee an everlasting light, and thy God thy glory.", "web": "The sun shall be no more your light by day; neither for brightness shall the moon give light to you: but Yahweh will be to you an everlasting light, and your God your glory.", "bsb": "No longer will the sun be your light by day, nor the brightness of the moon shine on your night; for the LORD will be your everlasting light, and your God will be your splendor.", "asv": "The sun shall be no more thy light by day; neither for brightness shall the moon give light unto thee: but Jehovah will be unto thee an everlasting light, and thy God thy glory.", "ylt": "To thee no more is the sun for a light by day, And for brightness the moon giveth not light to thee, And Jehovah hath become to thee A light age-during, and thy God thy beauty.", "dra": "Thou shalt no more have the sun for thy light by day, neither shall the brightness of the moon enlighten thee: but the Lord shall be unto thee for an everlasting light, and thy God for thy glory.", "bbe": "The sun will not be your light by day, and the moon will no longer be bright for you by night: but the Lord will be to you an eternal light, and your God your glory.", "geneva": "Thou shalt haue no more sunne to shine by day, neither shall the brightnesse of the moone shine vnto thee: for the Lord shall be thine euerlasting light, and thy God, thy glorie.", "wycliffe": "The sunne schal no more be to thee for to schyne bi dai, nether the briytnesse of the moone schal liytne thee; but the Lord schal be in to euerlastynge liyt to thee, and thi God schal be in to thi glorie.", "rotherham": "Thou shalt no more have the sun, for light by day, neither for brightness, shall the moon, give light unto thee,—But Yahweh shall become thine age-abiding light, And thy God thine adorning:", "darby": "The sun shall be no more thy light by day, neither for brightness shall the moon give light unto thee; but Jehovah shall be thine everlasting light, and thyGod thy glory.", "twenty": "", "jps": "The sun shall be no more thy light by day, neither for brightness shall the moon give light unto thee; but HaShem shall be unto thee an everlasting light, and thy G-d thy glory.", "acv": "The sun shall no more be thy light by day, nor for brightness shall the moon give light to thee, but Jehovah will be to thee an everlasting light, and thy God thy glory.", "anderson": "", "haweis": "", "noyes": "No more shall the sun be thy light by day, Nor with her brightness shall the moon enlighten thee: But Jehovah shall be to thee an everlasting light, And thy God thy glory.", "webster": "The sun shall be no more thy light by day; neither for brightness shall the moon give light to thee: but the LORD will be to thee an everlasting light, and thy God thy glory.", "vulgate": "non erit tibi amplius sol ad lucendum per diem nec splendor lunae inluminabit te sed erit tibi Dominus in lucem sempiternam et Deus tuus in gloriam tuam;", "brenton": "And thou shalt no more have the sun for a light by day, nor shall the rising of the moon lighten thy night; but the Lord shall be thine everlasting light, and God thy glory."}}, {"v": 20, "ref": "60:20", "o": "לֹא יָב֥וֹא עוֹד֙ שִׁמְשֵׁ֔/ךְ וִ/ירֵחֵ֖/ךְ לֹ֣א יֵאָסֵ֑ף כִּ֣י יְהוָ֗ה יִֽהְיֶה לָּ/ךְ֙ לְ/א֣וֹר עוֹלָ֔ם וְ/שָׁלְמ֖וּ יְמֵ֥י אֶבְלֵֽ/ךְ", "en": {"kjv": "Thy sun shall no more go down; neither shall thy moon withdraw itself: for the Lord shall be thine everlasting light, and the days of thy mourning shall be ended.", "web": "Your sun shall no more go down, neither shall your moon withdraw itself; for Yahweh will be your everlasting light, and the days of your mourning shall be ended.", "bsb": "Your sun will no longer set, and your moon will not wane; for the LORD will be your everlasting light, and the days of your sorrow will cease.", "asv": "Thy sun shall no more go down, neither shall thy moon withdraw itself; for Jehovah will be thine everlasting light, and the days of thy mourning shall be ended.", "ylt": "Thy sun goeth no more in, And thy moon is not removed, For Jehovah becometh to thee a light age-during. And the days of thy mourning have been completed.", "dra": "Thy sun shall go down no more, and thy moon shall not decrease: for the Lord shall be unto thee for an everlasting light, and the days of thy mourning shall be ended.", "bbe": "Your sun will never again go down, or your moon keep back her light: for the Lord will be your eternal light, and the days of your sorrow will be ended.", "geneva": "Thy sunne shall neuer goe downe, neither shall thy moone be hid: for the Lord shalbe thine euerlasting light, and the dayes of thy sorowe shalbe ended.", "wycliffe": "Thi sunne schal no more go doun, and thi moone schal not be decreessid; for the Lord schal be in to euerlastynge liyt to thee, and the daies of thi mourenyng schulen be fillid.", "rotherham": "No more shall go in, thy sun, Nor thy moon, withdraw itself,—For, Yahweh, will become to thee an age-abiding light, So shall be ended the days of thy mourning.", "darby": "Thy sun shall no more go down, neither shall thy moon withdraw itself; for Jehovah shall be thine everlasting light, and the days of thy mourning shall be ended.", "twenty": "", "jps": "Thy sun shall no more go down, Neither shall thy moon withdraw itself; for HaShem shall be thine everlasting light, and the days of thy mourning shall be ended.", "acv": "Thy sun shall no more go down, nor shall thy moon withdraw itself, for Jehovah will be thine everlasting light. And the days of thy mourning shall be ended.", "anderson": "", "haweis": "", "noyes": "Thy sun shall no more go down, Neither shall thy moon be hid; For Jehovah shall be thine everlasting light, And the days of thy mourning shall be ended.", "webster": "Thy sun shall no more go down; neither shall thy moon withdraw itself: for the LORD will be thy everlasting light, and the days of thy mourning shall be ended.", "vulgate": "non occidet ultra sol tuus et luna tua non minuetur quia Dominus erit in lucem sempiternam et conplebuntur dies luctus tui;", "brenton": "For the sun shall no more set, nor shall the moon be eclipsed; for the Lord shall be thine everlasting light, and the days of thy mourning shall be completed."}}, {"v": 21, "ref": "60:21", "o": "וְ/עַמֵּ/ךְ֙ כֻּלָּ֣/ם צַדִּיקִ֔ים לְ/עוֹלָ֖ם יִ֣ירְשׁוּ אָ֑רֶץ נֵ֧צֶר מטע/ו מַטָּעַ֛/י מַעֲשֵׂ֥ה יָדַ֖/י לְ/הִתְפָּאֵֽר", "en": {"kjv": "Thy people also shall be all righteous: they shall inherit the land for ever, the branch of my planting, the work of my hands, that I may be glorified.", "web": "Your people also shall be all righteous; they shall inherit the land forever, the branch of my planting, the work of my hands, that I may be glorified.", "bsb": "Then all your people will be righteous; they will possess the land forever; they are the branch of My planting, the work of My hands, so that I may be glorified.", "asv": "Thy people also shall be all righteous; they shall inherit the land for ever, the branch of my planting, the work of my hands, that I may be glorified.", "ylt": "And thy people are all of them righteous, To the age they possess the earth, A branch of My planting, A work of My hands, to be beautified.", "dra": "And thy people shall be all just, they shall inherit the land for ever, the branch of my planting, the work of my hand to glorify me.", "bbe": "Your people will all be upright, the land will be their heritage for ever; the branch of my planting, the work of my hands, to be for my glory.", "geneva": "Thy people also shalbe all righteous: they shall possesse the land for euer, the grasse of my planting shalbe the worke of mine handes, that I may be glorified.", "wycliffe": "Forsothe thi puple alle iust men, withouten ende schulen enherite the lond, the seed of my plauntyng, the werk of myn hond for to be glorified.", "rotherham": "And, thy people, shall all of them, be righteous, To times age-abiding, shall they possess, the land,—The sprout of mine own planting, The work of mine own hands,—That I may get myself glory.", "darby": "Thy people also shall be all righteous: they shall possess the land for ever — the branch of my planting, the work of my hands, that I may be glorified.", "twenty": "", "jps": "Thy people also shall be all righteous, they shall inherit the land for ever; the branch of My planting, the work of My hands, wherein I glory.", "acv": "Thy people also shall all be righteous. They shall inherit the land forever, the branch of my planting, the work of my hands, that I may be glorified.", "anderson": "", "haweis": "", "noyes": "Thy people shall be all righteous; Forever shall they possess the land, The scion of my planting, The work of my hands, that I may be glorified.", "webster": "Thy people also [shall be] all righteous: they shall inherit the land for ever, the branch of my planting, the work of my hands, that I may be glorified.", "vulgate": "populus autem tuus omnes iusti in perpetuum hereditabunt terram germen plantationis meae opus manus meae ad glorificandum;", "brenton": "Thy people also shall be all righteous; they shall inherit the land for ever, preserving that which they have planted, even the works of their hands, for glory."}}, {"v": 22, "ref": "60:22", "o": "הַ/קָּטֹן֙ יִֽהְיֶ֣ה לָ/אֶ֔לֶף וְ/הַ/צָּעִ֖יר לְ/ג֣וֹי עָצ֑וּם אֲנִ֥י יְהוָ֖ה בְּ/עִתָּ֥/הּ אֲחִישֶֽׁ/נָּה", "en": {"kjv": "A little one shall become a thousand, and a small one a strong nation: I the Lord will hasten it in his time.", "web": "The little one shall become a thousand, and the small one a strong nation; I, Yahweh, will hasten it in its time.”", "bsb": "The least of you will become a thousand, and the smallest a mighty nation. I am the LORD; in its time I will accomplish it quickly.", "asv": "The little one shall become a thousand, and the small one a strong nation; I, Jehovah, will hasten it in its time.", "ylt": "The little one doth become a chief, And the small one a mighty nation, I, Jehovah, in its own time do hasten it!", "dra": "The least shall become a thousand, and a little one a most strong nation: I the Lord will suddenly do this thing in its time.", "bbe": "The smallest of their families will become a thousand, and a small one a strong nation: I, the Lord, will make it come quickly in its time.", "geneva": "A litle one shall become as a thousande, and a small one as a strong nation: I the Lord wil hasten it in due time.", "wycliffe": "The leeste schal be in to a thousynde, and a litil man schal be in to a ful stronge folk. Y, the Lord, schal make this thing sudenli, in the tyme therof.", "rotherham": "The little one, shall become a thousand, and the small one, a mighty nation: I—Yahweh, in its own season, will hasten it.", "darby": "The little one shall become a thousand, and the smallest a mighty nation: I, Jehovah, will hasten it in its time.", "twenty": "", "jps": "The smallest shall become a thousand, and the least a mighty nation; I HaShem will hasten it in its time.", "acv": "The little one shall become a thousand, and the small one a strong nation. I, Jehovah, will hasten it in its time.", "anderson": "", "haweis": "", "noyes": "The little one shall become a thousand, And the small one a strong nation; I, Jehovah, will hasten it in its time.", "webster": "A little one shall become a thousand, and a small one a strong nation: I the LORD will hasten it in its time.", "vulgate": "minimus erit in mille et parvulus in gentem fortissimam ego Dominus in tempore eius subito faciam istud;", "brenton": "The little one shall become thousands, and the least a great nation; I the Lord will gather them in due time."}}]}, {"c": 61, "verses": [{"v": 1, "ref": "61:1", "o": "ר֛וּחַ אֲדֹנָ֥/י יְהוִ֖ה עָלָ֑/י יַ֡עַן מָשַׁח֩ יְהוָ֨ה אֹתִ֜/י לְ/בַשֵּׂ֣ר עֲנָוִ֗ים שְׁלָחַ֨/נִי֙ לַ/חֲבֹ֣שׁ לְ/נִשְׁבְּרֵי לֵ֔ב לִ/קְרֹ֤א לִ/שְׁבוּיִם֙ דְּר֔וֹר וְ/לַ/אֲסוּרִ֖ים פְּקַח קֽוֹחַ", "en": {"kjv": "The Spirit of the Lord God is upon me; because the Lord hath anointed me to preach good tidings unto the meek; he hath sent me to bind up the brokenhearted, to proclaim liberty to the captives, and the opening of the prison to them that are bound;", "web": "The Spirit of the Lord Yahweh is on me; because Yahweh has anointed me to preach good news to the humble. He has sent me to bind up the broken hearted, to proclaim liberty to the captives, and release to those who are bound;", "bsb": "The Spirit of the Lord GOD is on Me, because the LORD has anointed Me to preach good news to the poor. He has sent Me to bind up the brokenhearted, to proclaim liberty to the captives and freedom to the prisoners,", "asv": "The Spirit of the Lord Jehovah is upon me; because Jehovah hath anointed me to preach good tidings unto the meek; he hath sent me to bind up the broken-hearted, to proclaim liberty to the captives, and the opening of the prison to them that are bound;", "ylt": "The Spirit of the Lord Jehovah is on me, Because Jehovah did anoint me To proclaim tidings to the humble, He sent me to bind the broken of heart, To proclaim to captives liberty, And to bound ones an opening of bands.", "dra": "The spirit of the Lord is upon me, because the Lord hath anointed me: he hath sent me to preach to the meek, to heal the contrite of heart, and to preach a release to the captives, and deliverance to them that are shut up.", "bbe": "The spirit of the Lord is on me, because I am marked out by him to give good news to the poor; he has sent me to make the broken-hearted well, to say that the prisoners will be made free, and that those in chains will see the light again;", "geneva": "The Spirit of the Lord God is vpon mee, therefore hath the Lord anoynted mee: hee hath sent mee to preache good tidings vnto the poore, to binde vp the broken hearted, to preach libertie to the captiues, and to them that are bound, the opening of the prison,", "wycliffe": "The spirit of the Lord is on me, for the Lord anoyntide me; he sente me to telle to mylde men, that Y schulde heele men contrite in herte, and preche foryyuenesse to caitifs, and openyng to prisoneris; and preche a plesaunt yeer to the Lord,", "rotherham": "The spirit of My Lord Yahweh, is upon me,—Because Yahweh Hath anointed me to tell good tidings to the oppressed, Hath sent me to bind up the broken-hearted, To proclaim To captives, liberty, To them who are bound, the opening of the prison;", "darby": "The Spirit of the Lord Jehovah is upon me, because Jehovah hath anointed me to announce glad tidings unto the meek; he hath sent me to bind up the broken-hearted, to proclaim liberty to the captives, and opening of the prison to them that are bound;", "twenty": "", "jps": "The spirit of the L-rd GOD is upon me; because HaShem hath anointed me to bring good tidings unto the humble; He hath sent me to bind up the broken-hearted, to proclaim liberty to the captives, and the opening of the eyes to them that are bound;", "acv": "The Spirit of the lord Jehovah is upon me, because Jehovah has anointed me to preach good news to the poor. He has sent me to heal the broken-hearted, to proclaim liberty to the captives, and recovering of sight to the blind, and the opening of bonds to those who are bound,", "anderson": "", "haweis": "", "noyes": "The spirit of the Lord Jehovah is upon me, For Jehovah hath anointed me; He hath sent me to publish good tidings to the distressed, To bind up the broken-hearted, To proclaim liberty to the captives, And the opening of the prison to them that are bound;", "webster": "The Spirit of the Lord GOD [is] upon me; because the LORD hath anointed me to publish good tidings to the meek; he hath sent me to bind up the broken-hearted, to proclaim liberty to the captives, and the opening of the prison to [them that are] bound;", "vulgate": "spiritus Domini super me eo quod unxerit Dominus me ad adnuntiandum mansuetis misit me ut mederer contritis corde et praedicarem captivis indulgentiam et clausis apertionem;", "brenton": "The Spirit of the Lord is upon me, because he has anointed me; he has sent me to preach glad tidings to the poor, to heal the broken in heart, to proclaim liberty to the captives, and recovery of sight to the blind;"}}, {"v": 2, "ref": "61:2", "o": "לִ/קְרֹ֤א שְׁנַת רָצוֹן֙ לַֽ/יהוָ֔ה וְ/י֥וֹם נָקָ֖ם לֵ/אלֹהֵ֑י/נוּ לְ/נַחֵ֖ם כָּל אֲבֵלִֽים", "en": {"kjv": "To proclaim the acceptable year of the Lord, and the day of vengeance of our God; to comfort all that mourn;", "web": "to proclaim the year of Yahweh’s favor, and the day of vengeance of our God; to comfort all who mourn;", "bsb": "to proclaim the year of the LORD’s favor and the day of our God’s vengeance, to comfort all who mourn,", "asv": "to proclaim the year of Jehovah’s favor, and the day of vengeance of our God; to comfort all that mourn;", "ylt": "To proclaim the year of the good pleasure of Jehovah, And the day of vengeance of our God, To comfort all mourners.", "dra": "To proclaim the acceptable year of the Lord, and the day of vengeance of our God: to comfort all that mourn:", "bbe": "To give knowledge that the year of the Lord's good pleasure has come, and the day of punishment from our God; to give comfort to all who are sad;", "geneva": "To preache the acceptable yeere of the Lord, and the day of vengeance of our God, to comfort all that mourne,", "wycliffe": "and a dai of veniaunce to oure God; that Y schulde coumforte alle that mourenen;", "rotherham": "To proclaim—The year of acceptance of Yahweh, and The day of avenging of our God: To comfort all who are mourning;", "darby": "to proclaim the acceptable year of Jehovah, and the day of vengeance of ourGod; to comfort all that mourn;", "twenty": "", "jps": "To proclaim the year of HaShem'S good pleasure, and the day of vengeance of our G-d; to comfort all that mourn;", "acv": "to proclaim the acceptable year of Jehovah, and the day of vengeance of our God, to comfort all who mourn,", "anderson": "", "haweis": "", "noyes": "To proclaim the year of mercy from Jehovah, And the day of vengeance from our God; To comfort all that mourn;", "webster": "To proclaim the acceptable year of the LORD, and the day of vengeance of our God; to comfort all that mourn;", "vulgate": "ut praedicarem annum placabilem Domini et diem ultionis Deo nostro ut consolarer omnes lugentes;", "brenton": "to declare the acceptable year of the Lord, and the day of recompence; to comfort all that mourn;"}}, {"v": 3, "ref": "61:3", "o": "לָ/שׂ֣וּם לַ/אֲבֵלֵ֣י צִיּ֗וֹן לָ/תֵת֩ לָ/הֶ֨ם פְּאֵ֜ר תַּ֣חַת אֵ֗פֶר שֶׁ֤מֶן שָׂשׂוֹן֙ תַּ֣חַת אֵ֔בֶל מַעֲטֵ֣ה תְהִלָּ֔ה תַּ֖חַת ר֣וּחַ כֵּהָ֑ה וְ/קֹרָ֤א לָ/הֶם֙ אֵילֵ֣י הַ/צֶּ֔דֶק מַטַּ֥ע יְהוָ֖ה לְ/הִתְפָּאֵֽר", "en": {"kjv": "To appoint unto them that mourn in Zion, to give unto them beauty for ashes, the oil of joy for mourning, the garment of praise for the spirit of heaviness; that they might be called trees of righteousness, the planting of the Lord, that he might be glorified.", "web": "to appoint to those who mourn in Zion, to give to them a garland for ashes, the oil of joy for mourning, the garment of praise for the spirit of heaviness; that they may be called trees of righteousness, the planting of Yahweh, that he may be glorified.", "bsb": "to console the mourners in Zion— to give them a crown of beauty for ashes, the oil of joy for mourning, and a garment of praise for a spirit of despair. So they will be called oaks of righteousness, the planting of the LORD, that He may be glorified.", "asv": "to appoint unto them that mourn in Zion, to give unto them a garland for ashes, the oil of joy for mourning, the garment of praise for the spirit of heaviness; that they may be called trees of righteousness, the planting of Jehovah, that he may be glorified.", "ylt": "To appoint to mourners in Zion, To give to them beauty instead of ashes, The oil of joy instead of mourning, A covering of praise for a spirit of weakness, And He is calling to them, `Trees of righteousness, The planting of Jehovah--to be beautified.'", "dra": "To appoint to the mourners of Sion, and to give them a crown for ashes, the oil of joy for mourning, a garment of praise for the spirit of grief: and they shall be called in it the mighty ones of justice, the planting of the Lord to glorify him.", "bbe": "To give them a fair head-dress in place of dust, the oil of joy in place of the clothing of grief, praise in place of sorrow; so that they may be named trees of righteousness, the planting of the Lord, and so that he may have glory.", "geneva": "To appoint vnto them that mourne in Zion, and to giue vnto them beautie for ashes, the oyle of ioye for mourning, the garment of gladnesse for the spirit of heauinesse, that they might be called trees of righteousnesse, the planting of the Lord, that he might be glorified.", "wycliffe": "that Y schulde sette coumfort to the moureneris of Sion, and that Y schulde yyue to them a coroun for aische, oile of ioie for mourenyng, a mentil of preysyng for the spirit of weilyng. And stronge men of riytfulnesse schulen be clepid ther ynne, the plauntyng of the Lord for to glorifie.", "rotherham": "To appoint unto the mourners of Zion—To give unto them A chaplet instead of ashes, The oil of joy instead of mourning, The mantle of praise instead of the spirit of dejection,—So shall they be called The oaks of righteousness, The plantation of Yahweh: That he may get himself glory", "darby": "to appoint unto them that mourn in Zion, that beauty should be given unto them instead of ashes, the oil of joy instead of mourning, the garment of praise instead of the spirit of heaviness: that they might be called terebinths of righteousness, the planting of Jehovah, that he may be glorified.", "twenty": "", "jps": "To appoint unto them that mourn in Zion, to give unto them a garland for ashes, the oil of joy for mourning, the mantle of praise for the spirit of heaviness; that they might be called terebinths of righteousness, the planting of HaShem, wherein He might glory.", "acv": "to appoint to those who mourn in Zion, to give to them a garland for ashes, the oil of joy for mourning, the garment of praise for the spirit of heaviness, that they may be called trees of righteousness, the planting of Jehovah, that he may be glorified.", "anderson": "", "haweis": "", "noyes": "To give gladness to the mourners in Zion; To give them a beautiful crown instead of ashes, The oil of joy for mourning, The garment of praise for the spirit of heaviness, So that they shall be called blessed terebinth-trees, The plantation of Jehovah for his glory.", "webster": "To appoint to them that mourn in Zion, to give to them beauty for ashes, the oil of joy for mourning, the garment of praise for the spirit of heaviness; that they may be called trees of righteousness, the planting of the LORD, that he may be glorified.", "vulgate": "ut ponerem lugentibus Sion et darem eis coronam pro cinere oleum gaudii pro luctu pallium laudis pro spiritu maeroris et vocabuntur in ea fortes iustitiae plantatio Domini ad glorificandum;", "brenton": "that there should be given to them that mourn in Sion glory instead of ashes, the oil of joy to the mourners, the garment of glory for the spirit of heaviness: and they shall be called generations of righteousness, the planting of the Lord for glory."}}, {"v": 4, "ref": "61:4", "o": "וּ/בָנוּ֙ חָרְב֣וֹת עוֹלָ֔ם שֹׁמְמ֥וֹת רִֽאשֹׁנִ֖ים יְקוֹמֵ֑מוּ וְ/חִדְּשׁוּ֙ עָ֣רֵי חֹ֔רֶב שֹׁמְמ֖וֹת דּ֥וֹר וָ/דֽוֹר", "en": {"kjv": "And they shall build the old wastes, they shall raise up the former desolations, and they shall repair the waste cities, the desolations of many generations.", "web": "They shall build the old wastes, they shall raise up the former desolations, and they shall repair the waste cities, the desolations of many generations.", "bsb": "They will rebuild the ancient ruins; they will restore the places long devastated; they will renew the ruined cities, the desolations of many generations.", "asv": "And they shall build the old wastes, they shall raise up the former desolations, and they shall repair the waste cities, the desolations of many generations.", "ylt": "And they have built the wastes of old, The desolations of the ancients they raise up, And they have renewed waste cities, The desolations of generation and generation.", "dra": "And they shall build the places that have been waste from of old, and shall raise up ancient ruins, and shall repair the desolate cities, that were destroyed for generation and generation.", "bbe": "And they will be building again the old broken walls, and will make new the old waste places, and will put up again the towns which have been waste for long generations.", "geneva": "And they shall builde the olde waste places, and raise vp the former desolations, and they shall repaire the cities that were desolate and waste through many generations.", "wycliffe": "And thei schulen bilde thingis `that ben forsakun fro the world, and thei schulen reise elde fallyngis, and thei schulen restore citees `that ben forsakun and distried, in generacioun and in to generacioun.", "rotherham": "Then shall they build the wastes of a bygone age, The desolations of former times, shall they raise up,—And they shall build anew—The cities laid waste, The desolations of generation after generation.", "darby": "And they shall build the old wastes, they shall raise up the former desolations, and they shall repair the waste cities, the places desolate from generation to generation.", "twenty": "", "jps": "And they shall build the old wastes, they shall raise up the former desolations, and they shall renew the waste cities, the desolations of many generations.", "acv": "And they shall build the old wastes. They shall raise up the former desolations, and they shall repair the waste cities, the desolations of many generations.", "anderson": "", "haweis": "", "noyes": "They shall build up the old ruins; They shall raise up the ancient desolations; They shall repair the cities laid waste, The desolations of many generations.", "webster": "And they shall build the old wastes, they shall raise up the former desolations, and they shall repair the waste cities, the desolations of many generations.", "vulgate": "et aedificabunt deserta a saeculo et ruinas antiquas erigent et instaurabunt civitates desertas dissipatas in generationem et generationem;", "brenton": "And they shall build the old waste places, they shall raise up those that were before made desolate, and shall renew the desert cities, even those that had been desolate for many generations."}}, {"v": 5, "ref": "61:5", "o": "וְ/עָמְד֣וּ זָרִ֔ים וְ/רָע֖וּ צֹאנְ/כֶ֑ם וּ/בְנֵ֣י נֵכָ֔ר אִכָּרֵי/כֶ֖ם וְ/כֹרְמֵי/כֶֽם", "en": {"kjv": "And strangers shall stand and feed your flocks, and the sons of the alien shall be your plowmen and your vinedressers.", "web": "Strangers shall stand and feed your flocks, and foreigners shall work your fields and your vineyards.", "bsb": "Strangers will stand and feed your flocks, and foreigners will be your plowmen and vinedressers.", "asv": "And strangers shall stand and feed your flocks, and foreigners shall be your plowmen and your vine-dressers.", "ylt": "And strangers have stood and fed your flock, Sons of a foreigner are your husbandmen, And your vine-dressers.", "dra": "And strangers shall stand and shall feed your flocks: and the sons of strangers shall be your husbandman, and the dressers of your vines.", "bbe": "And men from strange countries will be your herdsmen, and those who are not Israelites will be your ploughmen and vine-keepers.", "geneva": "And the strangers shall stande and feede your sheepe, and the sonnes of the strangers shall be your plowmen and dressers of your vines.", "wycliffe": "And aliens schulen stonde, and fede youre beestis; and the sones of pilgrymes schulen be youre erthe tilieris and vyn tilieris.", "rotherham": "Then shall strangers stay and feed your flocks,—And, the sons of the foreigner, shall be your plowmen and your vinedressers.", "darby": "And strangers shall stand and feed your flocks, and the sons of the alien shall be your ploughmen and your vinedressers.", "twenty": "", "jps": "And strangers shall stand and feed your flocks, and aliens shall be your plowmen and your vinedressers.", "acv": "And strangers shall stand and feed your flocks, and foreigners shall be your plowmen and your vinedressers.", "anderson": "", "haweis": "", "noyes": "Strangers shall stand up and feed your flocks, And the sons of the alien shall be your ploughmen and vine-dressers;", "webster": "And strangers shall stand and feed your flocks, and the sons of the alien [shall be] your plowmen and your vine-dressers.", "vulgate": "et stabunt alieni et pascent pecora vestra et filii peregrinorum agricolae et vinitores vestri erunt;", "brenton": "And strangers shall come and feed thy flocks, and aliens shall be thy ploughmen and vine-dressers."}}, {"v": 6, "ref": "61:6", "o": "וְ/אַתֶּ֗ם כֹּהֲנֵ֤י יְהוָה֙ תִּקָּרֵ֔אוּ מְשָׁרְתֵ֣י אֱלֹהֵ֔י/נוּ יֵאָמֵ֖ר לָ/כֶ֑ם חֵ֤יל גּוֹיִם֙ תֹּאכֵ֔לוּ וּ/בִ/כְבוֹדָ֖/ם תִּתְיַמָּֽרוּ", "en": {"kjv": "But ye shall be named the Priests of the Lord: men shall call you the Ministers of our God: ye shall eat the riches of the Gentiles, and in their glory shall ye boast yourselves.", "web": "But you shall be named the priests of Yahweh; men will call you the ministers of our God: you will eat the wealth of the nations, and you will boast in their glory.", "bsb": "But you will be called the priests of the LORD; they will speak of you as ministers of our God; you will feed on the wealth of nations, and you will boast in their riches.", "asv": "But ye shall be named the priests of Jehovah; men shall call you the ministers of our God: ye shall eat the wealth of the nations, and in their glory shall ye boast yourselves.", "ylt": "And ye are called `Priests of Jehovah,' `Ministers of our God,' is said of you, The strength of nations ye consume, And in their honour ye do boast yourselves.", "dra": "But you shall be called the priests of the Lord: to you it shall be said: Ye ministers of our God: you shall eat the riches of the Gentiles, and you shall pride yourselves in their glory.", "bbe": "But you will be named the priests of the Lord, the servants of our God: you will have the wealth of the nations for your food, and you will be clothed with their glory.", "geneva": "But ye shall be named the Priestes of the Lord, and men shall say vnto you, The ministers of our God, Ye shall eate the riches of the Gentiles, and shalbe exalted with their glorie.", "wycliffe": "But ye schulen be clepid the preestis of the Lord; it schal be seid to you, Ye ben mynystris of oure God. Ye schulen ete the strengthe of hethene men, and ye schulen be onourid in the glorie of hem.", "rotherham": "But, ye, the priests of Yahweh, shall be called, The attendants of our God, shall ye be named,—The riches of the nations, shall ye eat, And in their glory, shall ye boast yourselves.", "darby": "But as for you, ye shall be called priests of Jehovah; it shall be said of you: Ministers of ourGod. Ye shall eat the wealth of the nations, and into their glory shall ye enter.", "twenty": "", "jps": "But ye shall be named the priests of HaShem, men shall call you the ministers of our G-d; ye shall eat the wealth of the nations, and in their splendour shall ye revel.", "acv": "But ye shall be named the priests of Jehovah. Men shall call you the ministers of our God. Ye shall eat the wealth of the nations, and in their glory ye shall boast yourselves.", "anderson": "", "haweis": "", "noyes": "But ye shall be named the priests of Jehovah, Men shall call you the ministers of our God. Ye shall eat the riches of the nations, And in their glory shall ye make your boast.", "webster": "But ye shall be named the Priests of the LORD: [men] shall call you the Ministers of our God: ye shall eat the riches of the Gentiles, and in their glory shall ye boast yourselves.", "vulgate": "vos autem sacerdotes Domini vocabimini ministri Dei nostri dicetur vobis fortitudinem gentium comedetis et in gloria earum superbietis;", "brenton": "But ye shall be called priests of the Lord, the ministers of God: ye shall eat the strength of nations, and shall be admired because of their wealth."}}, {"v": 7, "ref": "61:7", "o": "תַּ֤חַת בָּשְׁתְּ/כֶם֙ מִשְׁנֶ֔ה וּ/כְלִמָּ֖ה יָרֹ֣נּוּ חֶלְקָ֑/ם לָ/כֵ֤ן בְּ/אַרְצָ/ם֙ מִשְׁנֶ֣ה יִירָ֔שׁוּ שִׂמְחַ֥ת עוֹלָ֖ם תִּֽהְיֶ֥ה לָ/הֶֽם", "en": {"kjv": "For your shame ye shall have double; and for confusion they shall rejoice in their portion: therefore in their land they shall possess the double: everlasting joy shall be unto them.", "web": "Instead of your shame you shall have double; and instead of dishonor they shall rejoice in their portion: therefore in their land they shall possess double; everlasting joy shall be to them.", "bsb": "Instead of shame, My people will have a double portion, and instead of humiliation, they will rejoice in their share; and so they will inherit a double portion in their land, and everlasting joy will be theirs.", "asv": "Instead of your shame ye shall have double; and instead of dishonor they shall rejoice in their portion: therefore in their land they shall possess double; everlasting joy shall be unto them.", "ylt": "Instead of your shame and confusion, A second time they sing of their portion, Therefore in their land A second time do they take possession, Joy age-during is for them.", "dra": "For your double confusion and shame, they shall praise their part: therefore shall they receive double in their land, everlasting joy shall be unto them.", "bbe": "As they had twice as much grief, and marks of shame were their heritage, so in their land they will be rewarded twice over, and will have eternal joy.", "geneva": "For your shame you shall receiue double, and for confusion they shall reioyce in their portion: for in their lande they shall possesse the double: euerlasting ioy shall be vnto them.", "wycliffe": "For youre double schenschip and schame thei schulen preise the part of hem; for this thing thei schulen haue pesibli double thingis in her lond, and euerlastynge gladnesse schal be to hem.", "rotherham": "Instead of your shame,—double! and Instead of disgrace, they shall shout in triumph over their portion,—Therefore in their own land, shall they possess double, Joy age-abiding, shall be theirs.", "darby": "Instead of your shame [ye shall have] double; instead of confusion they shall celebrate with joy their portion: therefore in their land they shall possess the double; everlasting joy shall be unto them.", "twenty": "", "jps": "For your shame which was double, and for that they rejoiced: 'Confusion is their portion'; therefore in their land they shall possess double, everlasting joy shall be unto them.", "acv": "Instead of your shame ye shall have double, and instead of dishonor they shall rejoice in their portion. Therefore in their land they shall possess double. Everlasting joy shall be to them.", "anderson": "", "haweis": "", "noyes": "For your shame shall ye have a double reward; And for ignominy ye shall rejoice in your portion; Therefore in your land ye shall possess double; Everlasting joy shall be your portion.", "webster": "For your shame [ye shall have] double; and [for] confusion they shall rejoice in their portion: therefore in their land they shall possess the double: everlasting joy shall be to them.", "vulgate": "pro confusione vestra duplici et rubore laudabunt partem eorum propter hoc in terra sua duplicia possidebunt laetitia sempiterna erit eis;", "brenton": "Thus shall they inherit the land a second time, and everlasting joy shall be upon their head."}}, {"v": 8, "ref": "61:8", "o": "כִּ֣י אֲנִ֤י יְהוָה֙ אֹהֵ֣ב מִשְׁפָּ֔ט שֹׂנֵ֥א גָזֵ֖ל בְּ/עוֹלָ֑ה וְ/נָתַתִּ֤י פְעֻלָּתָ/ם֙ בֶּ/אֱמֶ֔ת וּ/בְרִ֥ית עוֹלָ֖ם אֶכְר֥וֹת לָ/הֶֽם", "en": {"kjv": "For I the Lord love judgment, I hate robbery for burnt offering; and I will direct their work in truth, and I will make an everlasting covenant with them.", "web": "“For I, Yahweh, love justice, I hate robbery with iniquity; and I will give them their recompense in truth, and I will make an everlasting covenant with them.", "bsb": "For I, the LORD, love justice; I hate robbery and iniquity; in My faithfulness I will give them their recompense and make an everlasting covenant with them.", "asv": "For I, Jehovah, love justice, I hate robbery with iniquity; and I will give them their recompense in truth, and I will make an everlasting covenant with them.", "ylt": "For I am Jehovah, loving judgment, Hating plunder for a burnt-offering, And I have given their wage in truth, And a covenant age-during I make for them.", "dra": "For I am the Lord that love judgment, and hate robbery in a holocaust: and I will make their work in truth, and I will make a perpetual covenant with them.", "bbe": "For I, the Lord, take pleasure in upright judging; I will not put up with the violent taking away of right; and I will certainly give them their reward, and I will make an eternal agreement with them.", "geneva": "For I the Lord loue iudgement and hate robberie for burnt offering, and I wil direct their worke in trueth, and will make an euerlasting couenant with them.", "wycliffe": "For Y am the Lord, louynge doom, and hatynge raueyn in brent sacrifice. And Y schal yyue the werk of hem in treuthe, and Y schal smyte to hem an euerlastynge boond of pees.", "rotherham": "For, I, Yahweh, am a lover of justice, Hating plunder, for an ascending-sacrifice, Therefore will I give their reward with faithfulness, And an age-abiding covenant, will I solemnise for them.", "darby": "For I, Jehovah, love judgment, I hate robbery with wrong; and I will give their recompence in truth, and I will make an everlasting covenant with them.", "twenty": "", "jps": "For I HaShem love justice, I hate robbery with iniquity; and I will give them their recompense in truth, and I will make an everlasting covenant with them.", "acv": "For I, Jehovah, love justice. I hate robbery with iniquity. And I will give them their recompense in truth. And I will make an everlasting covenant with them.", "anderson": "", "haweis": "", "noyes": "For I, Jehovah, love justice, I hate rapine and iniquity, I will give them their reward with faithfulness, And an everlasting covenant will I make with them.", "webster": "For I the LORD love judgment, I hate robbery for burnt-offering; and I will direct their work in truth, and I will make an everlasting covenant with them.", "vulgate": "quia ego Dominus diligens iudicium odio habens rapinam in holocausto et dabo opus eorum in veritate et foedus perpetuum feriam eis;", "brenton": "For I am the Lord who love righteousness, and hate robberies of injustice; and I will give their labour to the just, and will make an everlasting covenant with them."}}, {"v": 9, "ref": "61:9", "o": "וְ/נוֹדַ֤ע בַּ/גּוֹיִם֙ זַרְעָ֔/ם וְ/צֶאֱצָאֵי/הֶ֖ם בְּ/ת֣וֹךְ הָ/עַמִּ֑ים כָּל רֹֽאֵי/הֶם֙ יַכִּיר֔וּ/ם כִּ֛י הֵ֥ם זֶ֖רַע בֵּרַ֥ךְ יְהוָֽה", "en": {"kjv": "And their seed shall be known among the Gentiles, and their offspring among the people: all that see them shall acknowledge them, that they are the seed which the Lord hath blessed.", "web": "Their seed shall be known among the nations, and their offspring among the peoples; all who see them shall acknowledge them, that they are the seed which Yahweh has blessed.”", "bsb": "Their descendants will be known among the nations, and their offspring among the peoples. All who see them will acknowledge that they are a people the LORD has blessed.", "asv": "And their seed shall be known among the nations, and their offspring among the peoples; all that see them shall acknowledge them, that they are the seed which Jehovah hath blessed.", "ylt": "And known among nations hath been their seed, And their offspring in the midst of the peoples, All their beholders acknowledge them, For they are a seed Jehovah hath blessed.", "dra": "And they shall know their seed among the Gentiles, and their offspring in the midst of peoples: all that shall see them, shall know them, that these are the seed which the Lord hath blessed.", "bbe": "And their seed will be noted among the nations, and their offspring among the peoples: it will be clear to all who see them that they are the seed to which the Lord has given his blessing.", "geneva": "And their seede shall be knowen among the Gentiles, and their buddes among the people. All that see them, shall know them, that they are the seede which the Lord hath blessed.", "wycliffe": "And the seed of hem schal be knowun among folkis, and the buriownyng of hem in the myddis of puplis. Alle men that seen hem, schulen knowe hem, for these ben the seed, whom the Lord blesside.", "rotherham": "Then shall be known among the nations, their seed, And, their offspring, in the midst of the peoples,—All who see them, shall acknowledge them, That, they, are the seed that Yahweh hath blessed.", "darby": "And their seed shall be known among the nations, and their offspring among the peoples: all that see them shall acknowledge them, that they are a seed that Jehovah hath blessed.", "twenty": "", "jps": "And their seed shall be known among the nations, and their offspring among the peoples; all that see them shall acknowledge them, that they are the seed which HaShem hath blessed.", "acv": "And their seed shall be known among the nations, and their offspring among the peoples. All who see them shall acknowledge them, that they are the seed which Jehovah has blessed.", "anderson": "", "haweis": "", "noyes": "Their race shall be illustrious among the nations, And their offspring among the people; All that see them shall acknowledge That they are a race which Jehovah hath blessed.", "webster": "And their seed shall be known among the Gentiles, and their offspring among the people: all that see them shall acknowledge them, that they [are] the seed [which] the LORD hath blessed.", "vulgate": "et scietur in gentibus semen eorum et germen eorum in medio populorum omnes qui viderint eos cognoscent eos quia isti sunt semen cui benedixit Dominus;", "brenton": "And their seed shall be known among the Gentiles, and their offspring in the midst of peoples: every one that sees them shall take notice of them, that they are a seed blessed of God;"}}, {"v": 10, "ref": "61:10", "o": "שׂ֧וֹשׂ אָשִׂ֣ישׂ בַּֽ/יהוָ֗ה תָּגֵ֤ל נַפְשִׁ/י֙ בֵּֽ/אלֹהַ֔/י כִּ֤י הִלְבִּישַׁ֨/נִי֙ בִּגְדֵי יֶ֔שַׁע מְעִ֥יל צְדָקָ֖ה יְעָטָ֑/נִי כֶּֽ/חָתָן֙ יְכַהֵ֣ן פְּאֵ֔ר וְ/כַ/כַּלָּ֖ה תַּעְדֶּ֥ה כֵלֶֽי/הָ", "en": {"kjv": "I will greatly rejoice in the Lord, my soul shall be joyful in my God; for he hath clothed me with the garments of salvation, he hath covered me with the robe of righteousness, as a bridegroom decketh himself with ornaments, and as a bride adorneth herself with her jewels.", "web": "I will greatly rejoice in Yahweh, my soul shall be joyful in my God; for he has clothed me with the garments of salvation, he has covered me with the robe of righteousness, as a bridegroom decks himself with a garland, and as a bride adorns herself with her jewels.", "bsb": "I will rejoice greatly in the LORD, my soul will exult in my God; for He has clothed me with garments of salvation and wrapped me in a robe of righteousness, as a bridegroom wears a priestly headdress, as a bride adorns herself with her jewels.", "asv": "I will greatly rejoice in Jehovah, my soul shall be joyful in my God; for he hath clothed me with the garments of salvation, he hath covered me with the robe of righteousness, as a bridegroom decketh himself with a garland, and as a bride adorneth herself with her jewels.", "ylt": "I greatly rejoice in Jehovah, Joy doth my soul in my God, For He clothed me with garments of salvation, With a robe of righteousness covereth Me, As a bridegroom prepareth ornaments, And as a bride putteth on her jewels.", "dra": "I will greatly rejoice in the Lord, and my soul shall be joyful in my God: for he hath clothed me with the garments of salvation: and with the robe of justice he hath covered me, as a bridegroom decked with a crown, and as a bride adorned with her jewels.", "bbe": "I will be full of joy in the Lord, my soul will be glad in my God; for he has put on me the clothing of salvation, covering me with the robe of righteousness, as the husband puts on a fair head-dress, and the bride makes herself beautiful with jewels.", "geneva": "I will greatly reioyce in the Lord, and my soule shall be ioyfull in my God: for he hath clothed mee with the garments of saluation, and couered me with the robe of righteousnes: hee hath decked me like a bridegrome, and as a bride tireth herselfe with her iewels.", "wycliffe": "I ioiynge schal haue ioie in the Lord, and my soule schal make ful out ioiyng in my God. For he hath clothid me with clothis of helthe, and he hath compassid me with clothis of riytfulnesse, as a spouse made feir with a coroun, and as a spousesse ourned with her brochis.", "rotherham": "I will, greatly rejoice, in Yahweh, My soul shall exult in my God, For he hath clothed me with the garments of salvation, With a robe of righteousness, hath he enwrapt me,—As a bridegroom, adorneth himself with, a chaplet, And as a bride, bedecketh herself with, her jewels.", "darby": "I will greatly rejoice in Jehovah, my soul shall be joyful in myGod; for he hath clothed me with the garments of salvation, he hath covered me with the robe of righteousness, as a bridegroom decketh himself with the priestly turban, and as a bride adorneth herself with her jewels.", "twenty": "", "jps": "I will greatly rejoice in HaShem, my soul shall be joyful in my G-d; for He hath clothed me with the garments of salvation, He hath covered me with the robe of victory, as a bridegroom putteth on a priestly diadem, and as a bride adorneth herself with her jewels.", "acv": "I will greatly rejoice in Jehovah. My soul shall be joyful in my God, for he has clothed me with the garments of salvation. He has covered me with the robe of righteousness, as a bridegroom decks himself with a garland, and as a bride adorns herself with her jewels.", "anderson": "", "haweis": "", "noyes": "\"I will greatly rejoice in Jehovah; My soul shall exult in my God; For he hath clothed me with the garments of salvation; He hath covered me with the mantle of deliverance. As the bridegroom decketh himself with his turban, And as the bride adorneth herself with her jewels.\"", "webster": "I will greatly rejoice in the LORD, my soul shall be joyful in my God; for he hath clothed me with the garments of salvation, he hath covered me with the robe of righteousness, as a bridegroom decketh [himself] with ornaments, and as a bride adorneth [herself] with her jewels.", "vulgate": "gaudens gaudebo in Domino et exultabit anima mea in Deo meo quia induit me vestimentis salutis et indumento iustitiae circumdedit me quasi sponsum decoratum corona et quasi sponsam ornatam monilibus suis;", "brenton": "and they shall greatly rejoice in the Lord. Let my soul rejoice in the Lord; for he has clothed me with the robe of salvation, and the garment of joy: he has put a mitre on me as on a bridegroom, and adorned me with ornaments as a bride."}}, {"v": 11, "ref": "61:11", "o": "כִּ֤י כָ/אָ֨רֶץ֙ תּוֹצִ֣יא צִמְחָ֔/הּ וּ/כְ/גַנָּ֖ה זֵרוּעֶ֣י/הָ תַצְמִ֑יחַ כֵּ֣ן אֲדֹנָ֣/י יְהוִ֗ה יַצְמִ֤יחַ צְדָקָה֙ וּ/תְהִלָּ֔ה נֶ֖גֶד כָּל הַ/גּוֹיִֽם", "en": {"kjv": "For as the earth bringeth forth her bud, and as the garden causeth the things that are sown in it to spring forth; so the Lord God will cause righteousness and praise to spring forth before all the nations.", "web": "For as the earth produces its bud, and as the garden causes the things that are sown in it to spring out; so the Lord Yahweh will cause righteousness and praise to spring out before all the nations.", "bsb": "For as the earth brings forth its growth, and as a garden enables seed to spring up, so the Lord GOD will cause righteousness and praise to spring up before all the nations.", "asv": "For as the earth bringeth forth its bud, and as the garden causeth the things that are sown in it to spring forth; so the Lord Jehovah will cause righteousness and praise to spring forth before all the nations.", "ylt": "For, as the earth bringeth forth her shoots, And as a garden causeth its sown things to shoot up, So the Lord Jehovah causeth righteousness and praise To shoot up before all the nations!", "dra": "For as the earth bringeth forth her bud, and as the garden causeth her seed to shoot forth: so shall the Lord God make justice to spring forth, and praise before all the nations.", "bbe": "For as the earth puts out buds, and as the garden gives growth to the seeds which are planted in it, so the Lord will make righteousness and praise to be flowering before all the nations.", "geneva": "For as the earth bringeth foorth her bud, and as the garden causeth to growe that which is sowen in it: so the Lord God will cause righteousnesse to grow and praise before all the heathen.", "wycliffe": "For as the erthe bryngith forth his fruyt, and as a gardyn buriowneth his seed, so the Lord God schal make to growe riytfulnesse, and preysyng bifore alle folkis.", "rotherham": "For as the earth, bringeth forth her bud, And as, a garden, causeth her seeds, to shoot forth, So, My Lord, Yahweh, will cause to shoot forth Righteousness and praise before all the nations.", "darby": "For as the earth bringeth forth her bud, and as a garden causeth the things that are sown in it to spring forth, so the Lord Jehovah will cause righteousness and praise to spring forth before all the nations.", "twenty": "", "jps": "For as the earth bringeth forth her growth, and as the garden causeth the things that are sown in it to spring forth; so the L-rd GOD will cause victory and glory to spring forth before all the nations.", "acv": "For as the earth brings forth its bud, and as the garden causes the things that are sown in it to spring forth, so the lord Jehovah will cause righteousness and praise to spring forth before all the nations.", "anderson": "", "haweis": "", "noyes": "For as the earth putteth forth her shoots, And as a garden causeth its plants to spring forth, So shall the Lord Jehovah cause salvation to spring forth; And praise before all the nations.", "webster": "For as the earth bringeth forth her bud, and as the garden causeth the things that are sown in it to spring forth; so the Lord GOD will cause righteousness and praise to spring forth before all the nations.", "vulgate": "sicut enim terra profert germen suum et sicut hortus semen suum germinat sic Dominus Deus germinabit iustitiam et laudem coram universis gentibus;", "brenton": "And as the earth putting forth her flowers, and as a garden its seed; so shall the Lord, even the Lord, cause righteousness to spring forth, and exultation before all nations."}}]}, {"c": 62, "verses": [{"v": 1, "ref": "62:1", "o": "לְמַ֤עַן צִיּוֹן֙ לֹ֣א אֶחֱשֶׁ֔ה וּ/לְמַ֥עַן יְרוּשָׁלִַ֖ם לֹ֣א אֶשְׁק֑וֹט עַד יֵצֵ֤א כַ/נֹּ֨גַהּ֙ צִדְקָ֔/הּ וִ/ישׁוּעָתָ֖/הּ כְּ/לַפִּ֥יד יִבְעָֽר", "en": {"kjv": "For Zion’s sake will I not hold my peace, and for Jerusalem’s sake I will not rest, until the righteousness thereof go forth as brightness, and the salvation thereof as a lamp that burneth.", "web": "For Zion’s sake will I not hold my peace, and for Jerusalem’s sake I will not rest, until her righteousness go out as brightness, and her salvation as a lamp that burns.", "bsb": "For Zion’s sake I will not keep silent, and for Jerusalem’s sake I will not keep still, until her righteousness shines like a bright light, her salvation like a blazing torch.", "asv": "For Zion’s sake will I not hold my peace, and for Jerusalem’s sake I will not rest, until her righteousness go forth as brightness, and her salvation as a lamp that burneth.", "ylt": "For Zion's sake I am not silent, And for Jerusalem's sake I do not rest, Till her righteousness go out as brightness, And her salvation, as a torch that burneth.", "dra": "For Sion's sake I will not hold my peace, and for the sake of Jerusalem, I will not rest till her just one come forth as brightness, and her saviour be lighted as a lamp.", "bbe": "Because of Zion I will not keep quiet, and because of Jerusalem I will take no rest, till her righteousness goes out like the shining of the sun, and her salvation like a burning light.", "geneva": "For Zions sake I will not holde my tongue, and for Ierusalems sake I wil not rest, vntil the righteousnes thereof breake foorth as the light, and saluation thereof as a burning lampe.", "wycliffe": "For Sion Y schal not be stille, and for Jerusalem Y schal not reste, til the iust man therof go out as schynyng, and the sauyour therof be teendid as a laumpe.", "rotherham": "For Zion’s sake, will I not hold my peace, And for Jerusalem’s sake, will I not rest,—Until her righteousness, go forth as brightness, And her salvation, as a torch that is lighted.", "darby": "For Zion's sake will I not hold my peace, and for Jerusalem's sake I will not be still, until her righteousness go forth as brightness, and her salvation as a torch that burneth.", "twenty": "", "jps": "For Zion's sake will I not hold My peace, and for Jerusalem's sake I will not rest, until her triumph go forth as brightness, and her salvation as a torch that burneth.", "acv": "For Zion's sake I will not hold my peace, and for Jerusalem's sake I will not rest, until her righteousness goes forth as brightness, and her salvation as a lamp that burns.", "anderson": "", "haweis": "", "noyes": "For Zion’s sake I will not keep silence, And for Jerusalem’s sake I will not rest, Until her deliverance break forth like the shining light, And her salvation like a blazing torch.", "webster": "For Zion's sake I will not hold my peace, and for Jerusalem's sake I will not rest, until its righteousness shall go forth as brightness, and its salvation as a lamp [that] burneth.", "vulgate": "propter Sion non tacebo et propter Hierusalem non quiescam donec egrediatur ut splendor iustus eius et salvator eius ut lampas accendatur;", "brenton": "For Sion's sake I will not hold my peace, and for Jerusalem's sake I will not rest, until her righteousness go forth as light, and my salvation burn as a torch."}}, {"v": 2, "ref": "62:2", "o": "וְ/רָא֤וּ גוֹיִם֙ צִדְקֵ֔/ךְ וְ/כָל מְלָכִ֖ים כְּבוֹדֵ֑/ךְ וְ/קֹ֤רָא לָ/ךְ֙ שֵׁ֣ם חָדָ֔שׁ אֲשֶׁ֛ר פִּ֥י יְהוָ֖ה יִקֳּבֶֽ/נּוּ", "en": {"kjv": "And the Gentiles shall see thy righteousness, and all kings thy glory: and thou shalt be called by a new name, which the mouth of the Lord shall name.", "web": "The nations shall see your righteousness, and all kings your glory, and you shall be called by a new name, which the mouth of Yahweh shall name.", "bsb": "Nations will see your righteousness, and all kings your glory. You will be called by a new name that the mouth of the LORD will bestow.", "asv": "And the nations shall see thy righteousness, and all kings thy glory, and thou shalt be called by a new name, which the mouth of Jehovah shall name.", "ylt": "And nations have seen thy righteousness, And all kings thine honour, And He is giving to thee a new name, That the mouth of Jehovah doth define.", "dra": "And the Gentiles shall see thy just one, and all kings thy glorious one: and thou shalt be called by a new name, which the mouth of the Lord shall name.", "bbe": "And the nations will see your righteousness, and all kings your glory: and you will have a new name, given by the mouth of the Lord.", "geneva": "And the Gentiles shall see thy righteousnesse, and all Kings thy glory: and thou shalt be called by a new name, which the mouth of the Lord shall name.", "wycliffe": "And hethene men schulen se thi iust man, and alle kyngis schulen se thi noble man; and a newe name, which the mouth of the Lord nemyde, schal be clepid to thee.", "rotherham": "So shall nations see thy righteousness, And all kings, thy glory; And thou shalt be called by a new name, which, the mouth of Yahweh, will name.", "darby": "And the nations shall see thy righteousness, and all kings thy glory; and thou shalt be called by a new name, which the mouth of Jehovah will name.", "twenty": "", "jps": "And the nations shall see thy triumph, and all kings thy glory; and thou shalt be called by a new name, which the mouth of HaShem shall mark out.", "acv": "And the nations shall see thy righteousness, and all kings thy glory. And thou shall be called by a new name, which the mouth of Jehovah shall name.", "anderson": "", "haweis": "", "noyes": "Then shall the nations see thy prosperity, And all the kings thy glory; Thou shalt be called by a new name, Which the mouth of Jehovah shall give thee.", "webster": "And the Gentiles shall see thy righteousness, and all kings thy glory: and thou shalt be called by a new name, which the mouth of the LORD shall name.", "vulgate": "et videbunt gentes iustum tuum et cuncti reges inclitum tuum et vocabitur tibi nomen novum quod os Domini nominabit;", "brenton": "And the Gentiles shall see thy righteousness, and kings thy glory: and one shall call thee by a new name, which the Lord shall name."}}, {"v": 3, "ref": "62:3", "o": "וְ/הָיִ֛יתְ עֲטֶ֥רֶת תִּפְאֶ֖רֶת בְּ/יַד יְהוָ֑ה ו/צנוף וּ/צְנִ֥יף מְלוּכָ֖ה בְּ/כַף אֱלֹהָֽיִ/ךְ", "en": {"kjv": "Thou shalt also be a crown of glory in the hand of the Lord, and a royal diadem in the hand of thy God.", "web": "You shall also be a crown of beauty in the hand of Yahweh, and a royal diadem in the hand of your God.", "bsb": "You will be a crown of glory in the hand of the LORD, a royal diadem in the palm of your God.", "asv": "Thou shalt also be a crown of beauty in the hand of Jehovah, and a royal diadem in the hand of thy God.", "ylt": "And thou hast been a crown of beauty in the hand of Jehovah, And a diadem of royalty in the hand of thy God,", "dra": "And thou shalt be a crown of glory in the hand of the Lord, and a royal diadem in the hand of thy God.", "bbe": "And you will be a fair crown in the hand of the Lord, and a king's head-dress in the hand of your God.", "geneva": "Thou shalt also be a crowne of glory in the hand of the Lord, and a royall diademe in the hand of thy God.", "wycliffe": "And thou schalt be a coroun of glorie in the hond of the Lord, and a diademe of the rewme in the hond of thi God.", "rotherham": "Then shalt thou become—A crown of adorning, in the hand of Yahweh, and A royal diadem in the hand of thy God.", "darby": "And thou shalt be a crown of beauty in the hand of Jehovah, and a royal diadem in the hand of thyGod.", "twenty": "", "jps": "Thou shalt also be a crown of beauty in the hand of HaShem, and a royal diadem in the open hand of thy G-d.", "acv": "Thou shall also be a crown of beauty in the hand of Jehovah, and a royal diadem in the hand of thy God.", "anderson": "", "haweis": "", "noyes": "Thou shalt be a beautiful crown in the hand of Jehovah, A royal diadem in the hand of thy God.", "webster": "Thou shalt also be a crown of glory in the hand of the LORD, and a royal diadem in the hand of thy God.", "vulgate": "et eris corona gloriae in manu Domini et diadema regni in manu Dei tui;", "brenton": "And thou shalt be a crown of beauty in the hand of the Lord, and a royal diadem in the hand of thy God."}}, {"v": 4, "ref": "62:4", "o": "לֹֽא יֵאָמֵר֩ לָ֨/ךְ ע֜וֹד עֲזוּבָ֗ה וּ/לְ/אַרְצֵ/ךְ֙ לֹא יֵאָמֵ֥ר עוֹד֙ שְׁמָמָ֔ה כִּ֣י לָ֗/ךְ יִקָּרֵא֙ חֶפְצִי בָ֔הּ וּ/לְ/אַרְצֵ֖/ךְ בְּעוּלָ֑ה כִּֽי חָפֵ֤ץ יְהוָה֙ בָּ֔/ךְ וְ/אַרְצֵ֖/ךְ תִּבָּעֵֽל", "en": {"kjv": "Thou shalt no more be termed Forsaken; neither shall thy land any more be termed Desolate: but thou shalt be called Hephzi–bah, and thy land Beulah: for the Lord delighteth in thee, and thy land shall be married.", "web": "You shall no more be termed Forsaken; neither shall your land any more be termed Desolate: but you shall be called Hephzibah, and your land Beulah; for Yahweh delights in you, and your land shall be married.", "bsb": "No longer will you be called Forsaken, nor your land named Desolate; but you will be called Hephzibah, and your land Beulah; for the LORD will take delight in you, and your land will be His bride.", "asv": "Thou shalt no more be termed Forsaken; neither shall thy land any more be termed Desolate: but thou shalt be called Hephzi-bah, and thy land Beulah; for Jehovah delighteth in thee, and thy land shall be married.", "ylt": "It is not said of thee any more, `Forsaken!' And of thy land it is not said any more, `Desolate,' For to thee is cried, `My delight is in her,' And to thy land, `Married,' For Jehovah hath delighted in thee, And thy land is married.", "dra": "Thou shalt no more be called Forsaken: and thy land shall no more be called Desolate: but thou shalt be called My pleasure in her, and thy land inhabited. Because the Lord hath been well pleased with thee: and thy land shall be inhabited.", "bbe": "You will not now be named, She who is given up; and your land will no longer be named, The waste land: but you will have the name, My pleasure is in her, and your land will be named, Married: for the Lord has pleasure in you, and your land will be married.", "geneva": "It shall no more be sayd vnto thee, Forsaken, neither shall it be said any more to thy land, Desolate, but thou shalt be called Hephzi-bah, and thy land Beulah: for the Lord deliteth in thee, and thy land shall haue an husband.", "wycliffe": "Thou schalt no more be clepid forsakun, and thi lond schal no more be clepid desolat; but thou schalt be clepid My wille in that, and thi lond schal be enhabitid; for it plesid the Lord in thee, and thi lond schal be enhabited.", "rotherham": "Thou shalt he termed no longer—Forsaken Nor shall thy land be termed any longer A desolation, But, thou, shalt be called Hephzibah [=\"My delight is in her\"], And, thy land, Beulah [=\"married\"],—For Yahweh hath found delight in thee, And thy land, shall be married.", "darby": "Thou shalt no more be termed, Forsaken; neither shall thy land any more be termed, Desolate: but thou shalt be called, My delight is in her, and thy land, Married; for Jehovah delighteth in thee, and thy land shall be married.", "twenty": "", "jps": "Thou shalt no more be termed Forsaken, neither shall thy land any more be termed Desolate; but thou shalt be called, My delight is in her, and thy land, Espoused; for HaShem delighteth in thee, and thy land shall be espoused.", "acv": "Thou shall no more be termed Forsaken, nor shall thy land any more be termed Desolate. But thou shall be called Hephzi-bah, and thy land Beulah, for Jehovah delights in thee, and thy land shall be married.", "anderson": "", "haweis": "", "noyes": "No more shalt thou be called the Desolate, And thy land, the Forsaken. But thou shall be named My-delight-is-in-her. And thy land the wedded Matron. For Jehovah shall delight in thee, And thy land shall be married.", "webster": "Thou shalt no more be termed Forsaken; neither shall thy land any more be termed Desolate: but thou shalt be called Hephzi-bah, and thy land Beulah: for the LORD delighteth in thee, and thy land shall be married.", "vulgate": "non vocaberis ultra Derelicta et terra tua non vocabitur amplius Desolata sed vocaberis Voluntas mea in ea et terra tua Inhabitata quia conplacuit Domino in te et terra tua inhabitabitur;", "brenton": "And thou shalt no more be called Forsaken; and thy land shall no more be called Desert: for thou shalt be called My Pleasure, and thy land Inhabited: for the Lord has taken pleasure in thee, and thy land shall be inhabited."}}, {"v": 5, "ref": "62:5", "o": "כִּֽי יִבְעַ֤ל בָּחוּר֙ בְּתוּלָ֔ה יִבְעָל֖וּ/ךְ בָּנָ֑יִ/ךְ וּ/מְשׂ֤וֹשׂ חָתָן֙ עַל כַּלָּ֔ה יָשִׂ֥ישׂ עָלַ֖יִ/ךְ אֱלֹהָֽיִ/ךְ", "en": {"kjv": "For as a young man marrieth a virgin, so shall thy sons marry thee: and as the bridegroom rejoiceth over the bride, so shall thy God rejoice over thee.", "web": "For as a young man marries a virgin, so your sons shall marry you; and as the bridegroom rejoices over the bride, so your God will rejoice over you.", "bsb": "For as a young man marries a young woman, so your sons will marry you; and as a bridegroom rejoices over his bride, so your God will rejoice over you.", "asv": "For as a young man marrieth a virgin, so shall thy sons marry thee; and as the bridegroom rejoiceth over the bride, so shall thy God rejoice over thee.", "ylt": "For a young man doth marry a virgin, Thy Builders do marry thee, With the joy of a bridegroom over a bride, Rejoice over thee doth thy God.", "dra": "For the young man shall dwell with the virgin, and thy children shall dwell in thee. And the bridegroom shall rejoice over the bride, and thy God shall rejoice over thee.", "bbe": "For as a young man takes a virgin for his wife, so will your maker be married to you: and as a husband has joy in his bride, so will the Lord your God be glad over you.", "geneva": "For as a yong man marieth a virgine, so shall thy sonnes marry thee: and as a bridegrome is glad of the bride, so shall thy God reioyce ouer thee.", "wycliffe": "For a yong man schal dwelle with a virgyn, and thi sones schulen dwelle in thee; and the spouse schal haue ioie on the spousesse, and thi God schal haue ioie on thee.", "rotherham": "For a young man marrieth, a virgin, Thy sons marry thee! And the bridegroom rejoiceth over the bride—Thy God, rejoiceth over thee.", "darby": "For [as] a young man marrieth a virgin, shall thy sons marry thee; and with the joy of the bridegroom over the bride, shall thyGod rejoice over thee.", "twenty": "", "jps": "For as a young man espouseth a virgin, so shall thy sons espouse thee; and as the bridegroom rejoiceth over the bride, so shall thy G-d rejoice over thee.", "acv": "For as a young man marries a virgin, so shall thy sons marry thee. And as the bridegroom rejoices over the bride, so shall thy God rejoice over thee.", "anderson": "", "haweis": "", "noyes": "For as a young man weddeth a virgin. So shall thy children wed thee. And as a bridegroom rejoiceth in his bride, So shall thy God rejoice in thee.", "webster": "For [as] a young man marrieth a virgin, [so] shall thy sons marry thee: and [as] the bridegroom rejoiceth over the bride, [so] will thy God rejoice over thee.", "vulgate": "habitabit enim iuvenis cum virgine et habitabunt in te filii tui et gaudebit sponsus super sponsam gaudebit super te Deus tuus;", "brenton": "And as a young man lives with a virgin, so shall thy sons dwell in thee: and it shall come to pass that as a bridegroom will rejoice over a bride, so will the Lord rejoice over thee."}}, {"v": 6, "ref": "62:6", "o": "עַל חוֹמֹתַ֣יִ/ךְ יְרוּשָׁלִַ֗ם הִפְקַ֨דְתִּי֙ שֹֽׁמְרִ֔ים כָּל הַ/יּ֧וֹם וְ/כָל הַ/לַּ֛יְלָה תָּמִ֖יד לֹ֣א יֶחֱשׁ֑וּ הַ/מַּזְכִּרִים֙ אֶת יְהוָ֔ה אַל דֳּמִ֖י לָ/כֶֽם", "en": {"kjv": "I have set watchmen upon thy walls, O Jerusalem, which shall never hold their peace day nor night: ye that make mention of the Lord, keep not silence,", "web": "I have set watchmen on your walls, Jerusalem; they shall never hold their peace day nor night: you who call on Yahweh, take no rest,", "bsb": "On your walls, O Jerusalem, I have posted watchmen; they will never be silent day or night. You who call on the LORD shall take no rest for yourselves,", "asv": "I have set watchmen upon thy walls, O Jerusalem; they shall never hold their peace day nor night: ye that are Jehovah’s remembrancers, take ye no rest,", "ylt": "`On thy walls, O Jerusalem, I have appointed watchmen, All the day, and all the night, Continually, they are not silent.' O ye remembrancers of Jehovah, Keep not silence for yourselves,", "dra": "Upon thy walls, O Jerusalem, I have appointed watchmen all the day, and all the night, they shall never hold their peace. You that are mindful of the Lord, hold not your peace,", "bbe": "I have put watchmen on your walls, O Jerusalem; they will not keep quiet day or night: you who are the Lord's recorders, take no rest,", "geneva": "I haue set watchmen vpon thy walles, O Ierusalem, which all the day and all the night continually shall not cease: ye that are mindfull of the Lord, keepe not silence,", "wycliffe": "Jerusalem, Y haue ordeyned keperis on thi wallis, al dai and al niyt with outen ende thei schulen not be stille. Ye that thenken on the Lord, be not stille,", "rotherham": "Upon thy walls O Jerusalem, have I appointed watchmen, All the day and all the night through, let them not hold their peace,—O ye that put Yahweh in mind, Do not take rest to yourselves,", "darby": "I have set watchmen upon thy walls, Jerusalem; all the day and all the night they shall never hold their peace: ye that put Jehovah in remembrance, keep not silence,", "twenty": "", "jps": "I have set watchmen upon thy walls, O Jerusalem, they shall never hold their peace day nor night: 'Ye that are HaShem'S remembrancers, take ye no rest,", "acv": "I have set watchmen upon thy walls, O Jerusalem. They shall never keep silent day nor night. Ye who are Jehovah's reminders, take ye no rest,", "anderson": "", "haweis": "", "noyes": "Upon thy walls, O Jerusalem, have I set watchmen; All the day, and all the night, shall they not keep silence; O ye that praise Jehovah, keep not silence,", "webster": "I have set watchmen upon thy walls, O Jerusalem, [which] shall never hold their peace day nor night: ye that make mention of the LORD, keep not silence,", "vulgate": "super muros tuos Hierusalem constitui custodes tota die et tota nocte perpetuo non tacebunt qui reminiscimini Domini ne taceatis;", "brenton": "And on thy walls, O Jerusalem, have I set watchmen all day and all night, who shall never cease making mention of the Lord."}}, {"v": 7, "ref": "62:7", "o": "וְ/אַֽל תִּתְּנ֥וּ דֳמִ֖י ל֑/וֹ עַד יְכוֹנֵ֞ן וְ/עַד יָשִׂ֧ים אֶת יְרֽוּשָׁלִַ֛ם תְּהִלָּ֖ה בָּ/אָֽרֶץ", "en": {"kjv": "And give him no rest, till he establish, and till he make Jerusalem a praise in the earth.", "web": "and give him no rest, until he establishes, and until he makes Jerusalem a praise in the earth.", "bsb": "nor give Him any rest until He establishes Jerusalem and makes her the praise of the earth.", "asv": "and give him no rest, till he establish, and till he make Jerusalem a praise in the earth.", "ylt": "And give not silence to Him, Till He establish, and till He make Jerusalem A praise in the earth.", "dra": "And give him no silence till he establish, and till he make Jerusalem a praise in the earth.", "bbe": "And give him no rest, till he puts Jerusalem in her place to be praised in the earth.", "geneva": "And giue him no rest, till hee repaire and vntill hee set vp Ierusalem the prayse of the worlde.", "wycliffe": "and yyue ye not silence to him, til he stablische, and til he sette Jerusalem `preisyng in erthe.", "rotherham": "Neither give rest, unto him, Until he establish and until he set forth Jerusalem as a praise in the earth!", "darby": "and give him no rest, till he establish, and till he make Jerusalem a praise in the earth.", "twenty": "", "jps": "And give Him no rest, till He establish, and till He make Jerusalem a praise in the earth.'", "acv": "and give him no rest, till he establishes, and till he makes Jerusalem a praise in the earth.", "anderson": "", "haweis": "", "noyes": "And give him no rest, Until he establish Jerusalem, and make her a praise in the earth!", "webster": "And give him no rest, till he shall establish, and till he shall make Jerusalem a praise in the earth.", "vulgate": "et ne detis silentium ei donec stabiliat et donec ponat Hierusalem laudem in terra;", "brenton": "For there is none like you, when he shall have established, and made Jerusalem a praise on the earth."}}, {"v": 8, "ref": "62:8", "o": "נִשְׁבַּ֧ע יְהוָ֛ה בִּֽ/ימִינ֖/וֹ וּ/בִ/זְר֣וֹעַ עֻזּ֑/וֹ אִם אֶתֵּן֩ אֶת דְּגָנֵ֨/ךְ ע֤וֹד מַֽאֲכָל֙ לְ/אֹ֣יְבַ֔יִ/ךְ וְ/אִם יִשְׁתּ֤וּ בְנֵֽי נֵכָר֙ תִּֽירוֹשֵׁ֔/ךְ אֲשֶׁ֥ר יָגַ֖עַתְּ בּֽ/וֹ", "en": {"kjv": "The Lord hath sworn by his right hand, and by the arm of his strength, Surely I will no more give thy corn to be meat for thine enemies; and the sons of the stranger shall not drink thy wine, for the which thou hast laboured:", "web": "Yahweh has sworn by his right hand, and by the arm of his strength, “Surely I will no more give your grain to be food for your enemies; and foreigners shall not drink your new wine, for which you have labored:", "bsb": "The LORD has sworn by His right hand and by His mighty arm: “Never again will I give your grain to your enemies for food, nor will foreigners drink the new wine for which you have toiled.", "asv": "Jehovah hath sworn by his right hand, and by the arm of his strength, Surely I will no more give thy grain to be food for thine enemies; and foreigners shall not drink thy new wine, for which thou hast labored:", "ylt": "Sworn hath Jehovah by His right hand, Even by the arm of His strength: `I give not thy corn any more as food for thine enemies, Nor do sons of a stranger drink thy new wine, For which thou hast laboured.", "dra": "The Lord hath sworn by his right hand, and by the arm of his strength: Surely I will no more give thy corn to be meat for thy enemies: and the sons of the strangers shall not drink thy wine, for which thou hast laboured.", "bbe": "The Lord has taken an oath by his right hand, and by the arm of his strength, Truly, I will no longer give your grain to be food for your haters; and men of strange countries will not take the wine for which your work has been done:", "geneva": "The Lord hath sworne by his right hand and by his strong arme, Surely I wil no more giue thy corne to be meate for thine enemies, and surely the sonnes of the strangers shall not drinke thy wine, for the which thou hast laboured.", "wycliffe": "The Lord swoor in his riyt hond and in the arm of his strengthe, Y schal no more yyue thi wheete mete to thin enemyes, and alien sones schulen not drynke thi wyn, in which thou hast trauelid.", "rotherham": "Sworn hath Yahweh—By his own right hand, and By his own strong arm,—Surely I will give thy corn no more, as food to thine enemies, Nor shall the sons of the foreigner drink thy new wine, for which thou hast toiled;", "darby": "Jehovah hath sworn by his right hand and by the arm of his strength, I will indeed no more give thy corn [to be] food for thine enemies; and the sons of the alien shall not drink thy new wine, for which thou hast laboured;", "twenty": "", "jps": "HaShem hath sworn by His right hand, and by the arm of His strength: Surely I will no more give thy corn to be food for thine enemies; and strangers shall not drink thy wine, for which thou hast laboured;", "acv": "Jehovah has sworn by his right hand, and by the arm of his strength, Surely I will no more give thy grain to be food for thine enemies, and foreigners shall not drink thy new wine, for which thou have labored.", "anderson": "", "haweis": "", "noyes": "Jehovah hath sworn by his right hand, and his mighty arm: No more will I give thy corn to be food for thine enemies, Nor shall the sons of the stranger drink thy wine, for which thou hast labored.", "webster": "The LORD hath sworn by his right hand, and by the arm of his strength, Surely I will no more give thy corn [to be] food for thy enemies; and the sons of the stranger shall not drink thy wine, for which thou hast labored:", "vulgate": "iuravit Dominus in dextera sua et in brachio fortitudinis suae si dedero triticum tuum ultra cibum inimicis tuis et si biberint filii alieni vinum tuum in quo laborasti;", "brenton": "For the Lord has sworn by his glory, and by the might of his arm, I will no more give thy corn and thy provisions to thine enemies; nor shall strangers any more drink thy wine, for which thou has laboured."}}, {"v": 9, "ref": "62:9", "o": "כִּ֤י מְאַסְפָי/ו֙ יֹאכְלֻ֔/הוּ וְ/הִֽלְל֖וּ אֶת יְהוָ֑ה וּֽ/מְקַבְּצָ֥י/ו יִשְׁתֻּ֖/הוּ בְּ/חַצְר֥וֹת קָדְשִֽׁ/י", "en": {"kjv": "But they that have gathered it shall eat it, and praise the Lord; and they that have brought it together shall drink it in the courts of my holiness.", "web": "but those who have garnered it shall eat it, and praise Yahweh; and those who have gathered it shall drink it in the courts of my sanctuary.”", "bsb": "For those who harvest grain will eat it and praise the LORD, and those who gather grapes will drink the wine in My holy courts.”", "asv": "but they that have garnered it shall eat it, and praise Jehovah; and they that have gathered it shall drink it in the courts of my sanctuary.", "ylt": "For, those gathering it do eat it, and have praised Jehovah, And those collecting it do drink it in My holy courts.'", "dra": "For they that gather it, shall eat it, and shall praise the Lord: and they that bring it together, shall drink it in my holy courts.", "bbe": "But those who have got in the grain will have it for their food, and will give praise to the Lord; and those who have got in the grapes will take the wine of them in the open places of my holy house.", "geneva": "But they that haue gathered it, shall eate it, and prayse the Lord, and the gatherers thereof shall drinke it in the courtes of my Sanctuarie.", "wycliffe": "For thei that schulen gadere it togidere, schulen ete it, and schulen herie the Lord; and thei that beren it togidere, schulen drynke in myn hooli hallis.", "rotherham": "But they who have garnered it, shall eat it, and praise Yahweh,—And they who have gathered in its clusters, shall drink it in my holy courts.", "darby": "for they that have garnered it shall eat it, and praise Jehovah; and they that have gathered it shall drink it in the courts of my holiness.", "twenty": "", "jps": "But they that have garnered it shall eat it, and praise HaShem, and they that have gathered it shall drink it in the courts of My sanctuary.", "acv": "But those who have garnered it shall eat it, and praise Jehovah. And those who have gathered it shall drink it in the courts of my sanctuary.", "anderson": "", "haweis": "", "noyes": "But they that reap the harvest shall eat it, And praise Jehovah; And they that gather the vintage shall drink it, In my holy comets.", "webster": "But they that have gathered it shall eat it, and praise the LORD; and they that have collected it shall drink it in the courts of my holiness.", "vulgate": "quia qui congregabunt illud comedent et laudabunt Dominum et qui conportant illud bibent in atriis sanctis meis;", "brenton": "But they that have gathered them shall eat them, and they shall praise the Lord; and they that have gathered the grapes shall drink thereof in my holy courts."}}, {"v": 10, "ref": "62:10", "o": "עִבְר֤וּ עִבְרוּ֙ בַּ/שְּׁעָרִ֔ים פַּנּ֖וּ דֶּ֣רֶךְ הָ/עָ֑ם סֹ֣לּוּ סֹ֤לּוּ הַֽ/מְסִלָּה֙ סַקְּל֣וּ מֵ/אֶ֔בֶן הָרִ֥ימוּ נֵ֖ס עַל הָ/עַמִּֽים", "en": {"kjv": "Go through, go through the gates; prepare ye the way of the people; cast up, cast up the highway; gather out the stones; lift up a standard for the people.", "web": "Go through, go through the gates! Prepare the way of the people! Cast up, cast up the highway! Gather out the stones! Lift up a banner for the peoples.", "bsb": "Go out, go out through the gates; prepare the way for the people! Build it up, build up the highway; clear away the stones; raise a banner for the nations!", "asv": "Go through, go through the gates; prepare ye the way of the people; cast up, cast up the highway; gather out the stones; lift up an ensign for the peoples.", "ylt": "Pass ye on, pass on through the gates, Prepare ye the way of the people, Raise up, raise up the highway, clear it from stones, Lift up an ensign over the peoples.", "dra": "Go through, go through the gates, prepare the way for the people, make the road plain, pick out the stones, and lift up the standard to the people.", "bbe": "Go through, go through the doors; make ready the way of the people; let the highway be lifted up; let the stones be taken away; let a flag be lifted up over the peoples.", "geneva": "Go through, go through the gates: prepare you the way for the people: cast vp, cast vp the way, and gather out the stones and set vp a standart for the people.", "wycliffe": "Passe ye, passe ye bi the yatis; make ye redi weie to the puple, make ye a playn path; and chese ye stoonys, and reise ye a signe to puplis.", "rotherham": "Pass ye through pass ye through the gates, Prepare ye the way of the people,—Cast ye up, cast ye up the highway, Clear it of stones, Lift ye high a standard unto the peoples.", "darby": "Go through, go through the gates; prepare the way of the people; cast up, cast up the highway; gather out the stones; lift up a banner for the peoples.", "twenty": "", "jps": "Go through, go through the gates, clear ye the way of the people; cast up, cast up the highway, gather out the stones; lift up an ensign over the peoples.", "acv": "Go through, go through the gates. Prepare ye the way of the people. Cast up, cast up the highway. Gather out the stones. Lift up an ensign for the peoples.", "anderson": "", "haweis": "", "noyes": "Pass ye, pass ye through the gates; Prepare the way for the people; Cast ye up, cast ye up the highway, Clear it from the stones; Lift up on high a standard for the tribes!", "webster": "Go through, go through the gates; prepare ye the way of the people; cast up, cast up the highway; gather out the stones; lift up a standard for the people.", "vulgate": "transite transite per portas praeparate viam populo planum facite iter et eligite lapides elevate signum ad populos;", "brenton": "Go through my gates, and make a way for my people; and cast the stones out of the way; lift up a standard for the Gentiles."}}, {"v": 11, "ref": "62:11", "o": "הִנֵּ֣ה יְהוָ֗ה הִשְׁמִ֨יעַ֙ אֶל קְצֵ֣ה הָ/אָ֔רֶץ אִמְרוּ֙ לְ/בַת צִיּ֔וֹן הִנֵּ֥ה יִשְׁעֵ֖/ךְ בָּ֑א הִנֵּ֤ה שְׂכָר/וֹ֙ אִתּ֔/וֹ וּ/פְעֻלָּת֖/וֹ לְ/פָנָֽי/ו", "en": {"kjv": "Behold, the Lord hath proclaimed unto the end of the world, Say ye to the daughter of Zion, Behold, thy salvation cometh; behold, his reward is with him, and his work before him.", "web": "Behold, Yahweh has proclaimed to the end of the earth, “Say to the daughter of Zion, ‘Behold, your salvation comes. Behold, his reward is with him, and his recompense before him.’”", "bsb": "Behold, the LORD has proclaimed to the ends of the earth, “Say to Daughter Zion: See, your Savior comes! Look, His reward is with Him, and His recompense goes before Him.”", "asv": "Behold, Jehovah hath proclaimed unto the end of the earth, Say ye to the daughter of Zion, Behold, thy salvation cometh; behold, his reward is with him, and his recompense before him.", "ylt": "Lo, Jehovah hath proclaimed unto the end of the earth: `Say ye to the daughter of Zion, Lo, thy salvation hath come,' Lo, his hire is with him, and his wage before him.", "dra": "Behold the Lord hath made it to be heard in the ends of the earth, tell the daughter of Sion: Behold thy Saviour cometh: behold his reward is with him, and his work before him.", "bbe": "The Lord has sent out word to the end of the earth, Say to the daughter of Zion, See, your saviour comes; those whom he has made free are with him, and those to whom he has given salvation go before him.", "geneva": "Beholde, the Lord hath proclaimed vnto the endes of the world: tell the daughter Zion, Beholde, thy Sauiour commeth: beholde, his wages is with him, and his worke is before him.", "wycliffe": "Lo! the Lord made herd in the laste partis of the erthe. Seie ye to the douytir of Sion, Lo! thi sauyour cometh; lo! his meede is with hym, and his werk is bifore hym.", "rotherham": "Lo! Yahweh, hath sent a message unto the end of the earth: Say ye to the daughter of Zion, Lo! thy Salvation, is coming,—Lo! his reward, is with him, And, his recompense, before him:", "darby": "Behold, Jehovah hath proclaimed unto the end of the earth, Say ye to the daughter of Zion, Behold, thy salvation cometh; behold, his reward is with him, and his recompence before him.", "twenty": "", "jps": "Behold, HaShem hath proclaimed unto the end of the earth: say ye to the daughter of Zion: 'Behold, thy salvation cometh; behold, His reward is with Him, and His recompense before Him.'", "acv": "Behold, Jehovah has proclaimed to the end of the earth, Say ye to the daughter of Zion, Behold, thy salvation comes. Behold, his reward is with him, and his recompense before him.", "anderson": "", "haweis": "", "noyes": "Behold, Jehovah proclaimeth to the end of the earth: \"Say ye to the daughter of Zion, Behold, thy Deliverer cometh! Behold, his reward is with him, and his recompense before him!\"", "webster": "Behold, the LORD hath proclaimed to the end of the world, Say ye to the daughter of Zion, Behold, thy salvation cometh; Behold, his reward [is] with him, and his work before him.", "vulgate": "ecce Dominus auditum fecit in extremis terrae dicite filiae Sion ecce salvator tuus venit ecce merces eius cum eo et opus eius coram illo;", "brenton": "For behold, the Lord has proclaimed to the end of the earth, say ye to the daughter of Sion, Behold, thy Saviour has come to thee, having his reward and his work before his face."}}, {"v": 12, "ref": "62:12", "o": "וְ/קָרְא֥וּ לָ/הֶ֛ם עַם הַ/קֹּ֖דֶשׁ גְּאוּלֵ֣י יְהוָ֑ה וְ/לָ/ךְ֙ יִקָּרֵ֣א דְרוּשָׁ֔ה עִ֖יר לֹ֥א נֶעֱזָֽבָה", "en": {"kjv": "And they shall call them, The holy people, The redeemed of the Lord: and thou shalt be called, Sought out, A city not forsaken.", "web": "They shall call them The holy people, The redeemed of Yahweh: and you shall be called Sought out, A city not forsaken.", "bsb": "And they will be called the Holy People, the Redeemed of The LORD; and you will be called Sought Out, A City Not Forsaken.", "asv": "And they shall call them The holy people, The redeemed of Jehovah: and thou shalt be called Sought out, A city not forsaken.", "ylt": "And they have cried to them, `People of the Holy One, Redeemed of Jehovah,' Yea, to thee is called, `Sought out one, a city not forsaken!'", "dra": "And they shall call them, The holy people, the redeemed of the Lord. But thou shalt be called: A city sought after, and not forsaken.", "bbe": "And they will be named, The holy people, Those whose cause has been taken up by the Lord: and you will be named, Desired, A town not given up.", "geneva": "And they shall call them, The holy people, the redeemed of the Lord, and thou shalt be named, A citie sought out and not forsaken.", "wycliffe": "And thei schulen clepe hem the hooli puple, ayenbouyt of the Lord. Forsothe thou schalt be clepid a citee souyt, and not forsakun.", "rotherham": "So shall men call them—The holy people The redeemed of Yahweh,—And, thou, shalt be called—Sought out, A city not forsaken,", "darby": "And they shall call them, The holy people, The redeemed of Jehovah; and thou shalt be called, The sought out, The city not forsaken.", "twenty": "", "jps": "And they shall call them The holy people, the redeemed of HaShem; and thou shalt be called Sought out, a city not forsaken.", "acv": "And they shall call them The holy people, The redeemed of Jehovah. And thou shall be called Sought out, A city not forsaken.", "anderson": "", "haweis": "", "noyes": "They shall be called, The holy people, The redeemed of Jehovah. And thou shalt be called, The Sought out, The Not forsaken City.", "webster": "And they shall call them, The holy people, The redeemed of the LORD: and thou shalt be called, Sought out, A city not forsaken.", "vulgate": "et vocabunt eos Populus sanctus Redempti a Domino tu autem vocaberis Quaesita civitas et non Derelicta;", "brenton": "And one shall call them the holy people, the redeemed of the Lord: and thou shalt be called a city sought out, and not forsaken."}}]}, {"c": 63, "verses": [{"v": 1, "ref": "63:1", "o": "מִי זֶ֣ה בָּ֣א מֵ/אֱד֗וֹם חֲמ֤וּץ בְּגָדִים֙ מִ/בָּצְרָ֔ה זֶ֚ה הָד֣וּר בִּ/לְבוּשׁ֔/וֹ צֹעֶ֖ה בְּ/רֹ֣ב כֹּח֑/וֹ אֲנִ֛י מְדַבֵּ֥ר בִּ/צְדָקָ֖ה רַ֥ב לְ/הוֹשִֽׁיעַ", "en": {"kjv": "Who is this that cometh from Edom, with dyed garments from Bozrah? this that is glorious in his apparel, travelling in the greatness of his strength? I that speak in righteousness, mighty to save.", "web": "Who is this who comes from Edom, with dyed garments from Bozrah? this who is glorious in his clothing, marching in the greatness of his strength? “It is I who speak in righteousness, mighty to save.”", "bsb": "Who is this coming from Edom, from Bozrah with crimson-stained garments? Who is this robed in splendor, marching in the greatness of His strength? “It is I, proclaiming vindication, mighty to save.”", "asv": "Who is this that cometh from Edom, with dyed garments from Bozrah? this that is glorious in his apparel, marching in the greatness of his strength? I that speak in righteousness, mighty to save.", "ylt": "`Who is this coming from Edom? With dyed garments from Bozrah? This that is honourable in his clothing, Travelling in the abundance of his power?' --`I, speaking in righteousness, mighty to save.'", "dra": "Who is this that cometh from Edom, with dyed garments from Bosra, this beautiful one in his robe, walking in the greatness of his strength. I, that speak justice, and am a defender to save.", "bbe": "Who is this who comes from Edom, with blood-red robes from Bozrah? he whose clothing is fair, stepping with pride in his great strength? I whose glory is in the right, strong for salvation.", "geneva": "Who is this that commeth from Edom, with red garments from Bozrah? hee is glorious in his apparel and walketh in his great strength: I speake in righteousnesse, and am mightie to saue.", "wycliffe": "Who is this that cometh fro Edom, in died clothis fro Bosra? this fair man in his `long cloth, goynge in the multitude of his vertu? Y that speke riytfulnesse, and am a forfiytere for to saue.", "rotherham": "Who is this coming in from Edom With bright-red garments, from Bozrah? This made splendid in his raiment, Marching on in the greatness of his strength? I, speaking in righteousness, Mighty to save.", "darby": "Who is this that cometh from Edom, with deep-red garments from Bozrah, this that is glorious in his apparel, travelling in the greatness of his strength? — I that speak in righteousness, mighty to save.", "twenty": "", "jps": "'Who is this that cometh from Edom, with crimsoned garments from Bozrah? This that is glorious in his apparel, stately in the greatness of his strength?'--' I that speak in victory, mighty to save.'--", "acv": "Who is this who comes from Edom, with dyed garments from Bozrah, this who is glorious in his apparel, marching in the greatness of his strength? I who speak in righteousness, mighty to save.", "anderson": "", "haweis": "", "noyes": "Who is this that cometh from Edom? In scarlet garments from Bozrah? This that is glorious in his apparel, Proud in the greatness of his strength? I that proclaim deliverance, And am mighty to save.", "webster": "Who [is] this that cometh from Edom, with dyed garments from Bozrah? this [that is] glorious in his apparel, traveling in the greatness of his strength? I that speak in righteousness, mighty to save.", "vulgate": "quis est iste qui venit de Edom tinctis vestibus de Bosra iste formonsus in stola sua gradiens in multitudine fortitudinis suae ego qui loquor iustitiam et propugnator sum ad salvandum;", "brenton": "Who is this that is come from Edom, with red garments from Bosor? thus fair in his apparel, with mighty strength? I speak of righteousness and saving judgment."}}, {"v": 2, "ref": "63:2", "o": "מַדּ֥וּעַ אָדֹ֖ם לִ/לְבוּשֶׁ֑/ךָ וּ/בְגָדֶ֖י/ךָ כְּ/דֹרֵ֥ךְ בְּ/גַֽת", "en": {"kjv": "Wherefore art thou red in thine apparel, and thy garments like him that treadeth in the winefat?", "web": "Why are you red in your clothing, and your garments like him who treads in the wine vat?", "bsb": "Why are Your clothes red, and Your garments like one who treads the winepress?", "asv": "Wherefore art thou red in thine apparel, and thy garments like him that treadeth in the winevat?", "ylt": "`Wherefore is thy clothing red? And thy garments as treading in a wine fat?'", "dra": "Why then is thy apparel red, and thy garments like theirs that tread in the winepress?", "bbe": "Why is your clothing red, and why are your robes like those of one who is crushing the grapes?", "geneva": "Wherefore is thine apparel red, and thy garments like him that treadeth in ye wine presse?", "wycliffe": "Whi therfor is thi clothing reed? and thi clothis ben as of men stampynge in a pressour?", "rotherham": "Wherefore is there red, on thy raiment,—And thy garments as of one treading in a wine-trough?", "darby": "— Wherefore is redness in thine apparel, and thy garments like him that treadeth in the winevat?", "twenty": "", "jps": "'Wherefore is Thine apparel red, and Thy garments like his that treadeth in the winevat?'--", "acv": "Why are thou red in thine apparel, and thy garments like him who treads in the wine vat?", "anderson": "", "haweis": "", "noyes": "Wherefore is thine apparel red, And thy garments like those of one that treadeth the wine-vat?", "webster": "Why [art thou] red in thy apparel, and thy garments like him that treadeth in the wine-vat.", "vulgate": "quare ergo rubrum est indumentum tuum et vestimenta tua sicut calcantium in torculari;", "brenton": "Wherefore are thy garments red, and thy raiment as if fresh from a trodden winepress?"}}, {"v": 3, "ref": "63:3", "o": "פּוּרָ֣ה דָּרַ֣כְתִּי לְ/בַדִּ֗/י וּ/מֵֽ/עַמִּים֙ אֵֽין אִ֣ישׁ אִתִּ֔/י וְ/אֶדְרְכֵ֣/ם בְּ/אַפִּ֔/י וְ/אֶרְמְסֵ֖/ם בַּ/חֲמָתִ֑/י וְ/יֵ֤ז נִצְחָ/ם֙ עַל בְּגָדַ֔/י וְ/כָל מַלְבּוּשַׁ֖/י אֶגְאָֽלְתִּי", "en": {"kjv": "I have trodden the winepress alone; and of the people there was none with me: for I will tread them in mine anger, and trample them in my fury; and their blood shall be sprinkled upon my garments, and I will stain all my raiment.", "web": "“I have trodden the wine press alone; and of the peoples there was no man with me: yes, I trod them in my anger, and trampled them in my wrath; and their lifeblood is sprinkled on my garments, and I have stained all my clothing.", "bsb": "“I have trodden the winepress alone, and no one from the nations was with Me. I trampled them in My anger and trod them down in My fury; their blood spattered My garments, and all My clothes were stained.", "asv": "I have trodden the winepress alone; and of the peoples there was no man with me: yea, I trod them in mine anger, and trampled them in my wrath; and their lifeblood is sprinkled upon my garments, and I have stained all my raiment.", "ylt": "--`A wine-press I have trodden by myself, And of the peoples there is no one with me, And I tread them in mine anger, And I trample them in my fury, Sprinkled is their strength on my garments, And all my clothing I have polluted.", "dra": "I have trodden the winepress alone, and of the Gentiles there is not a man with me: I have trampled on them in my indignation, and have trodden them down in my wrath, and their blood is sprinkled upon my garments, and I have stained all my apparel.", "bbe": "I have been crushing the grapes by myself, and of the peoples there was no man with me: in my wrath and in my passion, they were crushed under my feet; and my robes are marked with their life-blood, and all my clothing is red.", "geneva": "I haue troden the wine presse alone, and of all people there was none with mee: for I will treade them in mine anger, and tread them vnder foote in my wrath, and their blood shalbe sprinkled vpon my garments, and I will staine all my raiment.", "wycliffe": "Y aloone stampide the presse, and of folkis no man is with me; Y stampide hem in my stronge veniaunce, and Y defoulide hem in my wraththe; and her blood is spreynt on my clothis, and Y made foul alle my clothis.", "rotherham": "A winepress, have I trodden, alone, And of the peoples, there was no man with me. So I trod them down in mine anger, And trampled upon them, in mine indignation,—And their life-blood besprinkled my garments, And all mine apparel, I defiled;", "darby": "I have trodden the winepress alone, and of the peoples not a man was with me; and I have trodden them in mine anger, and trampled them in my fury; and their blood is sprinkled upon my garments, and I have stained all mine apparel.", "twenty": "", "jps": "'I have trodden the winepress alone, and of the peoples there was no man with Me; yea, I trod them in Mine anger, and trampled them in My fury; and their lifeblood is dashed against My garments, and I have stained all My raiment.", "acv": "I have trodden the winepress alone, and of the peoples there was no man with me. Yea, I trod them in my anger, and trampled them in my wrath, and their lifeblood is sprinkled upon my garments, and I have stained all my raiment.", "anderson": "", "haweis": "", "noyes": "I have trodden the wine-vat alone, And of the nations there was none with me. And I trod them in mine anger, And I trampled them in my fury, So that their life-blood was sprinkled upon my garments. And I have stained all my apparel.", "webster": "I have trodden the wine-press alone; and of the people [there was] none with me: for I will tread them in my anger, and trample them in my fury, and their blood shall be sprinkled upon my garments, and I will stain all my raiment.", "vulgate": "torcular calcavi solus et de gentibus non est vir mecum calcavi eos in furore meo et conculcavi eos in ira mea et aspersus est sanguis eorum super vestimenta mea et omnia indumenta mea inquinavi;", "brenton": "I am full of trodden grape, and of the nations there is not a man with me; and I trampled them in my fury, and dashed them to pieces as earth, and brought down their blood to the earth."}}, {"v": 4, "ref": "63:4", "o": "כִּ֛י י֥וֹם נָקָ֖ם בְּ/לִבִּ֑/י וּ/שְׁנַ֥ת גְּאוּלַ֖/י בָּֽאָה", "en": {"kjv": "For the day of vengeance is in mine heart, and the year of my redeemed is come.", "web": "For the day of vengeance was in my heart, and the year of my redeemed has come.", "bsb": "For the day of vengeance was in My heart, and the year of My redemption had come.", "asv": "For the day of vengeance was in my heart, and the year of my redeemed is come.", "ylt": "For the day of vengeance is in my heart, And the year of my redeemed hath come.", "dra": "For the day of vengeance is in my heart, the year of my redemption is come.", "bbe": "For the day of punishment is in my heart, and the year for the payment of the price for my people has come.", "geneva": "For the day of vengeance is in mine heart, and the yeere of my redeemed is come.", "wycliffe": "For whi a dai of veniaunce is in myn herte, and the yeer of my yeldyng cometh.", "rotherham": "For, a day of avenging, was in my heart, And the year of my redeemed, had come.", "darby": "For the day of vengeance was in my heart, and the year of my redeemed had come.", "twenty": "", "jps": "For the day of vengeance that was in My heart, and My year of redemption are come.", "acv": "For the day of vengeance was in my heart, and the year of my redeemed has come.", "anderson": "", "haweis": "", "noyes": "For the day of vengeance was in my heart, And the year of my deliverance was come.", "webster": "For the day of vengeance [is] in my heart, and the year of my redeemed is come.", "vulgate": "dies enim ultionis in corde meo annus redemptionis meae venit;", "brenton": "For the day of recompence has come upon them, and the year of redemption is at hand."}}, {"v": 5, "ref": "63:5", "o": "וְ/אַבִּיט֙ וְ/אֵ֣ין עֹזֵ֔ר וְ/אֶשְׁתּוֹמֵ֖ם וְ/אֵ֣ין סוֹמֵ֑ךְ וַ/תּ֤וֹשַֽׁע לִ/י֙ זְרֹעִ֔/י וַ/חֲמָתִ֖/י הִ֥יא סְמָכָֽתְ/נִי", "en": {"kjv": "And I looked, and there was none to help; and I wondered that there was none to uphold: therefore mine own arm brought salvation unto me; and my fury, it upheld me.", "web": "I looked, and there was no one to help; and I wondered that there was no one to uphold: therefore my own arm brought salvation to me; and my wrath, it upheld me.", "bsb": "I looked, but there was no one to help; I was appalled that no one assisted. So My arm brought Me salvation, and My own wrath upheld Me.", "asv": "And I looked, and there was none to help; and I wondered that there was none to uphold: therefore mine own arm brought salvation unto me; and my wrath, it upheld me.", "ylt": "And I look attentively, and there is none helping, And I am astonished that there is none supporting, And give salvation to me doth mine own arm. And my wrath--it hath supported me.", "dra": "I looked about, and there was none to help: I sought, and there was none to give aid: and my own arm hath saved for me, and my indignation itself hath helped me.", "bbe": "And I saw that there was no helper, and I was wondering that no one gave them support: so my arm did the work of salvation, and my wrath was my support.", "geneva": "And I looked, and there was none to helpe, and I wondered that there was none to vpholde: therefore mine owne arme helped me, and my wrath it selfe sustained me.", "wycliffe": "I lokide aboute, and noon helpere was; Y souyte, and noon was that helpide; and myn arm sauyde to me, and myn indignacioun, that helpide me.", "rotherham": "Therefore looked I around, and there was none to help,—And I was astonished that there was none to uphold,—So, mine own arm brought me salvation, And mine indignation, the same upheld me;", "darby": "And I looked, and there was none to help; and I wondered that there was none to uphold: and mine own arm brought salvation unto me; and my fury, it upheld me.", "twenty": "", "jps": "And I looked, and there was none to help, and I beheld in astonishment, and there was none to uphold; therefore Mine own arm brought salvation unto Me, and My fury, it upheld Me.", "acv": "And I looked, and there was none to help. And I wondered that there was none to uphold. Therefore my own arm brought salvation to me. And my wrath, it upheld me.", "anderson": "", "haweis": "", "noyes": "And I looked, and there was none to help, And I wondered, that there was none to uphold; Therefore my own arm wrought salvation for me, And my fury, it sustained me.", "webster": "And I looked, and [there was] none to help; and I wondered that [there was] none to uphold: therefore my own arm brought salvation to me; and my fury, it upheld me.", "vulgate": "circumspexi et non erat auxiliator quaesivi et non fuit qui adiuvaret et salvavit mihi brachium meum et indignatio mea ipsa auxiliata est mihi;", "brenton": "And I looked, and there was no helper; and I observed, and none upheld: therefore my arm delivered them, and mine anger drew nigh."}}, {"v": 6, "ref": "63:6", "o": "וְ/אָב֤וּס עַמִּים֙ בְּ/אַפִּ֔/י וַ/אֲשַׁכְּרֵ֖/ם בַּ/חֲמָתִ֑/י וְ/אוֹרִ֥יד לָ/אָ֖רֶץ נִצְחָֽ/ם", "en": {"kjv": "And I will tread down the people in mine anger, and make them drunk in my fury, and I will bring down their strength to the earth.", "web": "I trod down the peoples in my anger, and made them drunk in my wrath, and I poured out their lifeblood on the earth.”", "bsb": "I trampled the nations in My anger; in My wrath I made them drunk and poured out their blood on the ground.”", "asv": "And I trod down the peoples in mine anger, and made them drunk in my wrath, and I poured out their lifeblood on the earth.", "ylt": "And I tread down peoples in mine anger, And I make them drunk in my fury, And I bring down to earth their strength.", "dra": "And I have trodden down the people in my wrath, and have made them drunk in my indignation, and have brought down their strength to the earth.", "bbe": "And in my passion the peoples were crushed under my feet, and broken in my wrath, and I put down their strength to the earth.", "geneva": "Therefore I wil tread downe the people in my wrath, and make them drunken in mine indignation, and wil bring downe their strength to the earth.", "wycliffe": "And Y defoulide puplis in my stronge veniaunce; and Y made hem drunkun in myn indignacioun, and Y drow doun her vertu in to erthe.", "rotherham": "Then trod I down peoples in mine anger, And make them drunk with mine indignation, And brought down to the earth their life-blood.", "darby": "And I have trodden down the peoples in mine anger, and made them drunk in my fury; and their blood have I brought down to the earth.", "twenty": "", "jps": "And I trod down the peoples in Mine anger, and made them drunk with My fury, and I poured out their lifeblood on the earth.'", "acv": "And I trod down the peoples in my anger, and made them drunk in my wrath, and I poured out their lifeblood on the earth.", "anderson": "", "haweis": "", "noyes": "I trod down the nations in my anger; I crushed them in my fury, And spilled their blood upon the ground.", "webster": "And I will tread down the people in my anger, and make them drunk in my fury, and I will bring down their strength to the earth.", "vulgate": "et conculcavi populos in furore meo et inebriavi eos in indignatione mea et detraxi in terra virtutem eorum;", "brenton": "And I trampled them in mine anger, and brought down their blood to the earth."}}, {"v": 7, "ref": "63:7", "o": "חַֽסְדֵ֨י יְהוָ֤ה אַזְכִּיר֙ תְּהִלֹּ֣ת יְהוָ֔ה כְּ/עַ֕ל כֹּ֥ל אֲשֶׁר גְּמָלָ֖/נוּ יְהוָ֑ה וְ/רַב טוּב֙ לְ/בֵ֣ית יִשְׂרָאֵ֔ל אֲשֶׁר גְּמָלָ֥/ם כְּֽ/רַחֲמָ֖י/ו וּ/כְ/רֹ֥ב חֲסָדָֽי/ו", "en": {"kjv": "I will mention the lovingkindnesses of the Lord, and the praises of the Lord, according to all that the Lord hath bestowed on us, and the great goodness toward the house of Israel, which he hath bestowed on them according to his mercies, and according to the multitude of his lovingkindnesses.", "web": "I will make mention of the loving kindnesses of Yahweh and the praises of Yahweh, according to all that Yahweh has bestowed on us, and the great goodness toward the house of Israel, which he has bestowed on them according to his mercies, and according to the multitude of his loving kindnesses.", "bsb": "I will make known the LORD’s loving devotion and His praiseworthy acts, because of all that the LORD has done for us— the many good things for the house of Israel according to His great compassion and loving devotion.", "asv": "I will make mention of the lovingkindnesses of Jehovah, and the praises of Jehovah, according to all that Jehovah hath bestowed on us, and the great goodness toward the house of Israel, which he hath bestowed on them according to his mercies, and according to the multitude of his lovingkindnesses.", "ylt": "The kind acts of Jehovah I make mention of, The praises of Jehovah, According to all that Jehovah hath done for us, And the abundance of the goodness to the house of Israel, That He hath done for them, According to His mercies, And according to the abundance of His kind acts.", "dra": "I will remember the tender mercies of the Lord, the praise of the Lord for all the things that the Lord hath bestowed upon us, and for the multitude of his good things to the house of Israel, which he hath given them according to his kindness, and according to the multitude of his mercies.", "bbe": "I will give news of the mercies of the Lord, and his great acts, even all the things the Lord has done for us, in his great grace to the house of Israel; even all he has done for us in his unnumbered mercies.", "geneva": "I wil remember the mercies of the Lord and the prayses of the Lord according vnto all that the Lord hath giuen vs, and for the great goodnesse toward the house of Israel, which hee hath giuen them according to his tender loue, and according to his great mercies.", "wycliffe": "I schal haue mynde on the merciful doyngis of the Lord, Y schal preche the heriyng of the Lord on alle thingis whiche the Lord yeldide to vs, and on the multitude `of goodis of the hous of Israel, whiche he yaf to hem bi his foryyuenesse, and bi the multitude of hise mercies.", "rotherham": "The lovingkindness of Yahweh, will I recall the praises of Yahweh, According to all that Yahweh hath bestowed upon us,—Even the abundance of goodness to the house of Israel, Which he bestowed upon them—According to his compassions and According to the abundance of his lovingkindness.", "darby": "I will record the loving-kindnesses of Jehovah, the praises of Jehovah, according to all that Jehovah hath bestowed upon us, and the great goodness toward the house of Israel which he hath bestowed upon them according to his mercies, and according to the multitude of his loving-kindnesses.", "twenty": "", "jps": "I will make mention of the mercies of HaShem, and the praises of HaShem, according to all that HaShem hath bestowed on us; and the great goodness toward the house of Israel, which He hath bestowed on them according to His compassions, and according to the multitude of His mercies.", "acv": "I will make mention of the loving kindnesses of Jehovah, and the praises of Jehovah, according to all that Jehovah has bestowed on us, and the great goodness toward the house of Israel, which he has bestowed on them according to his mercies, and according to the multitude of his loving kindnesses.", "anderson": "", "haweis": "", "noyes": "I will celebrate the mercy of Jehovah, the glory of Jehovah, According to all that he hath done for us; His great goodness to the house of Israel, Which he hath bestowed on it in his tender mercy, and his great kindness.", "webster": "I will mention the loving-kindnesses of the LORD, [and] the praises of the LORD, according to all that the LORD hath bestowed on us, and the great goodness towards the house of Israel, which he hath bestowed on them according to his mercies, and according to the multitude of his loving-kindnesses.", "vulgate": "miserationum Domini recordabor laudem Domini super omnibus quae reddidit nobis Dominus et super multitudinem bonorum domui Israhel quae largitus est eis secundum indulgentiam suam et secundum multitudinem misericordiarum suarum;", "brenton": "I remembered the mercy of the Lord, the praises of the Lord in all things wherein he recompenses us. The Lord is a good judge to the house of Israel; he deals with us according to his mercy, and according to the abundance of his righteousness."}}, {"v": 8, "ref": "63:8", "o": "וַ/יֹּ֨אמֶר֙ אַךְ עַמִּ֣/י הֵ֔מָּה בָּנִ֖ים לֹ֣א יְשַׁקֵּ֑רוּ וַ/יְהִ֥י לָ/הֶ֖ם לְ/מוֹשִֽׁיעַ", "en": {"kjv": "For he said, Surely they are my people, children that will not lie: so he was their Saviour.", "web": "For he said, “Surely, they are my people, children who will not deal falsely:” so he was their Savior.", "bsb": "For He said, “They are surely My people, sons who will not be disloyal.” So He became their Savior.", "asv": "For he said, Surely, they are my people, children that will not deal falsely: so he was their Saviour.", "ylt": "And He saith, Only My people they are , Sons--they lie not, and He is to them for a saviour.", "dra": "And he said: Surely they are my people, children that will not deny: so he became their saviour.", "bbe": "For he said, Truly they are my people, children who will not be false: so he was their saviour out of all their trouble.", "geneva": "For he saide, Surely they are my people, children that wil not lie: so he was their Sauiour.", "wycliffe": "And the Lord seide, Netheles it is my puple, sones not denyynge, and he was maad a sauyour to hem in al the tribulacioun of hem.", "rotherham": "Therefore he said—Surely my people, they are, Sons, they will not act falsely! So he became their saviour.", "darby": "And he said, They are indeed my people, children that will not lie; and he became their Saviour.", "twenty": "", "jps": "For He said: 'Surely, they are My people, children that will not deal falsely'; so He was their Saviour.", "acv": "For he said, Surely, they are my people, sons that will not deal falsely. So he was their Savior.", "anderson": "", "haweis": "", "noyes": "He said, Truly they are my people; Children that will not be false; So he was their deliverer.", "webster": "For he said, Surely they [are] my people, children [that] will not lie: so he was their Savior.", "vulgate": "et dixit verumtamen populus meus est filii non negantes et factus est eis salvator;", "brenton": "And he said, Is it not my people? the children surely will not be rebellious: and he became to them deliverance"}}, {"v": 9, "ref": "63:9", "o": "בְּֽ/כָל צָרָתָ֣/ם לא ל֣/וֹ צָ֗ר וּ/מַלְאַ֤ךְ פָּנָי/ו֙ הֽוֹשִׁיעָ֔/ם בְּ/אַהֲבָת֥/וֹ וּ/בְ/חֶמְלָת֖/וֹ ה֣וּא גְאָלָ֑/ם וַֽ/יְנַטְּלֵ֥/ם וַֽ/יְנַשְּׂאֵ֖/ם כָּל יְמֵ֥י עוֹלָֽם", "en": {"kjv": "In all their affliction he was afflicted, and the angel of his presence saved them: in his love and in his pity he redeemed them; and he bare them, and carried them all the days of old.", "web": "In all their affliction he was afflicted, and the angel of his presence saved them: in his love and in his pity he redeemed them; and he bore them, and carried them all the days of old.", "bsb": "In all their distress, He too was afflicted, and the Angel of His Presence saved them. In His love and compassion He redeemed them; He lifted them up and carried them all the days of old.", "asv": "In all their affliction he was afflicted, and the angel of his presence saved them: in his love and in his pity he redeemed them; and he bare them, and carried them all the days of old.", "ylt": "In all their distress He is no adversary, And the messenger of His presence saved them, In His love and in His pity He redeemed them, And He doth lift them up, And beareth them all the days of old.", "dra": "In all their affliction he was not troubled, and the angel of his presence saved them: in his love, and in his mercy he redeemed them, and he carried them and lifted them up all the days of old.", "bbe": "It was no sent one or angel, but he himself who was their saviour: in his love and in his pity he took up their cause, and he took them in his arms, caring for them all through the years.", "geneva": "In all their troubles he was troubled, and the Angel of his presence saued them: in his loue and in his mercie he redeemed them, and he bare them and caried them alwayes continually.", "wycliffe": "It was not set in tribulacioun, and the aungel of his face sauyde hem. In his loue and in his foryyuenesse he ayenbouyte hem, and he bar hem, and reiside hem in alle daies of the world.", "rotherham": "In all their affliction, he, was afflicted And the messenger of his presence saved them, In his love and in his pity, he, redeemed them,—And then lifted them up and carried them all the days of the age-past time.", "darby": "In all their affliction he was afflicted, and the Angel of his presence saved them: in his love and in his pity he redeemed them; and he bore them and carried them all the days of old.", "twenty": "", "jps": "In all their affliction He was afflicted, and the angel of His presence saved them; in His love and in His pity He redeemed them; and He bore them, and carried them all the days of old.", "acv": "In all their affliction he was afflicted, and the agent of his presence saved them. In his love and in his pity he redeemed them. And he bore them, and carried them all the days of old.", "anderson": "", "haweis": "", "noyes": "In all their straits they had no distress; An angel of his presence saved them; In his love and compassion he redeemed them, He took them up and bore them all the days of old.", "webster": "In all their affliction he was afflicted, and the angel of his presence saved them: in his love and in his pity he redeemed them; and he bore them, and carried them all the days of old.", "vulgate": "in omni tribulatione eorum non est tribulatus et angelus faciei eius salvavit eos in dilectione sua et in indulgentia sua ipse redemit eos et portavit eos et levavit eos cunctis diebus saeculi;", "brenton": "out of all their affliction: not an ambassador, nor a messenger, but himself saved them, because he loved them and spared them: he himself redeemed them, and took them up, and lifted them up all the days of old."}}, {"v": 10, "ref": "63:10", "o": "וְ/הֵ֛מָּה מָר֥וּ וְ/עִצְּב֖וּ אֶת ר֣וּחַ קָדְשׁ֑/וֹ וַ/יֵּהָפֵ֥ךְ לָ/הֶ֛ם לְ/אוֹיֵ֖ב ה֥וּא נִלְחַם בָּֽ/ם", "en": {"kjv": "But they rebelled, and vexed his holy Spirit: therefore he was turned to be their enemy, and he fought against them.", "web": "But they rebelled, and grieved his holy Spirit: therefore he was turned to be their enemy, and he himself fought against them.", "bsb": "But they rebelled and grieved His Holy Spirit. So He turned and became their enemy, and He Himself fought against them.", "asv": "But they rebelled, and grieved his holy Spirit: therefore he was turned to be their enemy, andhimself fought against them.", "ylt": "And they have rebelled and grieved His Holy Spirit, And He turneth to them for an enemy, He Himself hath fought against them.", "dra": "But they provoked to wrath, and afflicted the spirit of his Holy One: and he was turned to be their enemy, and he fought against them.", "bbe": "But they went against him, causing grief to his holy spirit: so he was turned against them, and made war on them.", "geneva": "But they rebelled and vexed his holy Spirit: therefore was hee turned to be their enemie and he fought against them.", "wycliffe": "Forsothe thei excitiden hym to wrathfulnesse, and turmentiden the spirit of his hooli; and he was turned in to an enemye to hem, and he ouercam hem in batel.", "rotherham": "But, they, rebelled, and grieved his Holy Spirit,—And so he turned against them as an enemy, he himself, fought against them.", "darby": "But they rebelled and grieved his holy Spirit: and he turned to be their enemy; himself, he fought against them.", "twenty": "", "jps": "But they rebelled, and grieved His holy spirit; therefore He was turned to be their enemy, Himself fought against them.", "acv": "But they rebelled, and grieved his holy Spirit. Therefore he was turned to be their enemy, and himself fought against them.", "anderson": "", "haweis": "", "noyes": "But they rebelled, and grieved his holy spirit; Then did he change himself into their enemy; He himself fought against them.", "webster": "But they rebelled, and vexed his holy Spirit: therefore he was turned to be their enemy, [and] he fought against them.", "vulgate": "ipsi autem ad iracundiam provocaverunt et adflixerunt spiritum Sancti eius et conversus est eis in inimicum et ipse debellavit eos;", "brenton": "But they disobeyed, and provoked his Holy Spirit: so he turned to be an enemy, he himself contended against them."}}, {"v": 11, "ref": "63:11", "o": "וַ/יִּזְכֹּ֥ר יְמֵֽי עוֹלָ֖ם מֹשֶׁ֣ה עַמּ֑/וֹ אַיֵּ֣ה הַֽ/מַּעֲלֵ֣/ם מִ/יָּ֗ם אֵ֚ת רֹעֵ֣י צֹאנ֔/וֹ אַיֵּ֛ה הַ/שָּׂ֥ם בְּ/קִרְבּ֖/וֹ אֶת ר֥וּחַ קָדְשֽׁ/וֹ", "en": {"kjv": "Then he remembered the days of old, Moses, and his people, saying, Where is he that brought them up out of the sea with the shepherd of his flock? where is he that put his holy Spirit within him?", "web": "Then he remembered the days of old, Moses and his people, saying, Where is he who brought them up out of the sea with the shepherds of his flock? where is he who put his holy Spirit in their midst?", "bsb": "Then His people remembered the days of old, the days of Moses. Where is He who brought them through the sea with the shepherds of His flock? Where is the One who set His Holy Spirit among them,", "asv": "Then he remembered the days of old, Mosesandhis people, saying, Where is he that brought them up out of the sea with the shepherds of his flock? where is he that put his holy Spirit in the midst of them?", "ylt": "And He remembereth the days of old, Moses--his people. Where is He who is bringing them up from the sea, The shepherd of his flock? Where is He who is putting in its midst His Holy Spirit?", "dra": "And he remembered the days of old of Moses, and of his people: Where is he that brought them up out of the sea, with the shepherds of his flock? where is he that put in the midst of them the spirit of his Holy One?", "bbe": "Then the early days came to their minds, the days of Moses his servant: and they said, Where is he who made the keeper of his flock come up from the sea? where is he who put his holy spirit among them,", "geneva": "Then he remembred the olde time of Moses and his people, saying, Where is hee that brought them vp out of the Sea with the shepheard of his sheepe? where is he that put his holy Spirit within him?", "wycliffe": "And he hadde mynde on the daies of the world, of Moises, and of his puple. Where is he, that ledde hem out of the see, with the scheepherdis of his floc? Where is he, that settide the spirit of his holi in the myddil therof;", "rotherham": "Then were recalled the days of the age-past time Moses—his people:—Where is he that led them up out of the sea with the shepherds of his flock? Where is he that put within him his Holy Spirit?", "darby": "But he remembered the days of old, Moses [and] his people: Where is he that brought them up out of the sea with the shepherds of his flock? Where is he that put his holy Spirit within him,", "twenty": "", "jps": "Then His people remembered the days of old, the days of Moses: 'Where is He that brought them up out of the sea with the shepherds of His flock? Where is He that put His holy spirit in the midst of them?", "acv": "Then he remembered the days of old, Moses and his people, saying, Where is he who brought them up out of the sea with the shepherds of his flock? Where is he who put his holy Spirit in the midst of them,", "anderson": "", "haweis": "", "noyes": "Then remembered his people the ancient days, the days of Moses, [saying,] Where is he that brought them up from the sea with the shepherd of his flock? Where is he that put his holy spirit within him?", "webster": "Then he remembered the days of old, Moses, [and] his people, [saying], Where [is] he that brought them out of the sea with the shepherd of his flock? where [is] he that put his holy Spirit within him?", "vulgate": "et recordatus est dierum saeculi Mosi populi sui ubi est qui eduxit eos de mari cum pastoribus gregis sui ubi est qui posuit in medio eius spiritum Sancti sui;", "brenton": "Then he remembered the ancient days, saying, Where is he that brought up from the sea the shepherd of the sheep? where is he that put his Holy Spirit in them?"}}, {"v": 12, "ref": "63:12", "o": "מוֹלִיךְ֙ לִ/ימִ֣ין מֹשֶׁ֔ה זְר֖וֹעַ תִּפְאַרְתּ֑/וֹ בּ֤וֹקֵֽעַ מַ֨יִם֙ מִ/פְּנֵי/הֶ֔ם לַ/עֲשׂ֥וֹת ל֖/וֹ שֵׁ֥ם עוֹלָֽם", "en": {"kjv": "That led them by the right hand of Moses with his glorious arm, dividing the water before them, to make himself an everlasting name?", "web": "who caused his glorious arm to go at the right hand of Moses? who divided the waters before them, to make himself an everlasting name?", "bsb": "who sent His glorious arm to lead them by the right hand of Moses, who divided the waters before them to gain for Himself everlasting renown,", "asv": "that caused his glorious arm to go at the right hand of Moses? that divided the waters before them, to make himself an everlasting name?", "ylt": "Leading by the right hand of Moses, the arm of His glory, Cleaving waters from before them, To make to Himself a name age-during.", "dra": "He that brought out Moses by the right hand, by the arm of his majesty: that divided the waters before them, to make himself an everlasting name.", "bbe": "He who made the arm of his glory go at the right hand of Moses, by whom the waters were parted before them, to make himself an eternal name;", "geneva": "He led them by the right hand of Moses with his owne glorious arme, deuiding the water before them, to make himselfe an euerlasting Name.", "wycliffe": "whiche ledde out Moises to the riyt half in the arm of his maieste? which departide watris bifore hem, that he schulde make to hym silf a name euerlastynge;", "rotherham": "That caused to go at the right hand of Moses his own majestic arm,—Cleaving the waters from before them, To make himself an age-abiding name:", "darby": "his glorious arm leading them by the right hand of Moses, dividing the waters before them, to make himself an everlasting name,", "twenty": "", "jps": "That caused His glorious arm to go at the right hand of Moses? that divided the water before them, to make Himself an everlasting name?", "acv": "who caused his glorious arm to go at the right hand of Moses, who divided the waters before them, to make himself an everlasting name,", "anderson": "", "haweis": "", "noyes": "That caused his glorious arm to accompany the right hand of Moses, That divided the water before them, To make to himself an everlasting name?", "webster": "That led [them] by the right hand of Moses with his glorious arm, dividing the water before them, to make himself an everlasting name?", "vulgate": "qui eduxit ad dexteram Mosen brachio maiestatis suae qui scidit aquas ante eos ut faceret sibi nomen sempiternum;", "brenton": "who led Moses with his right hand, the arm of his glory? he forced the water to separate from before him, to make himself an everlasting name."}}, {"v": 13, "ref": "63:13", "o": "מוֹלִיכָ֖/ם בַּ/תְּהֹמ֑וֹת כַּ/סּ֥וּס בַּ/מִּדְבָּ֖ר לֹ֥א יִכָּשֵֽׁלוּ", "en": {"kjv": "That led them through the deep, as an horse in the wilderness, that they should not stumble?", "web": "who led them through the depths, as a horse in the wilderness, so that they didn’t stumble?", "bsb": "who led them through the depths like a horse in the wilderness, so that they did not stumble?", "asv": "that led them through the depths, as a horse in the wilderness, so that they stumbled not?", "ylt": "Leading them through the depths, As a horse in a plain they stumble not.", "dra": "He that led them out through the deep, as a horse in the wilderness that stumbleth not.", "bbe": "He who made them go through the deep waters, like a horse in the waste land?", "geneva": "Hee led them through the deepe, as an horse in the wildernesse, that they should not stumble,", "wycliffe": "whiche ledde hem out thoruy depthis of watris, as an hors not stumblynge in desert,", "rotherham": "Causing them to go through the roaring deeps,—Like a horse through the wilderness, That they should not stumble?", "darby": "— who led them through the depths, like a horse in the wilderness, [and] they stumbled not?", "twenty": "", "jps": "That led them through the deep, as a horse in the wilderness, without stumbling?", "acv": "who led them through the depths, as a horse in the wilderness, so that they stumbled not?", "anderson": "", "haweis": "", "noyes": "That led them through the deep, As a horse through a desert, without stumbling?", "webster": "That led them through the deep, as a horse in the wilderness, [that] they should not stumble?", "vulgate": "qui duxit eos per abyssos quasi equum in deserto non inpingentem;", "brenton": "He led them through the deep, as a horse through the wilderness, and they fainted not,"}}, {"v": 14, "ref": "63:14", "o": "כַּ/בְּהֵמָה֙ בַּ/בִּקְעָ֣ה תֵרֵ֔ד ר֥וּחַ יְהוָ֖ה תְּנִיחֶ֑/נּוּ כֵּ֚ן נִהַ֣גְתָּ עַמְּ/ךָ֔ לַ/עֲשׂ֥וֹת לְ/ךָ֖ שֵׁ֥ם תִּפְאָֽרֶת", "en": {"kjv": "As a beast goeth down into the valley, the Spirit of the Lord caused him to rest: so didst thou lead thy people, to make thyself a glorious name.", "web": "As the livestock that go down into the valley, the Spirit of Yahweh caused them to rest; so you led your people, to make yourself a glorious name.", "bsb": "Like cattle going down to the valley, the Spirit of the LORD gave them rest. You led Your people this way to make for Yourself a glorious name.", "asv": "As the cattle that go down into the valley, the Spirit of Jehovah caused them to rest: so didst thou lead thy people, to make thyself a glorious name.", "ylt": "As a beast into a valley goeth down, The Spirit of Jehovah causeth him to rest, So hast Thou led Thy people, To make to Thyself a glorious name.", "dra": "As a beast that goeth down in the field, the spirit of the Lord was their leader: so didst thou lead thy people to make thyself a glorious name.", "bbe": "Like the cattle which go down into the valley, they went without falling, the spirit of the Lord guiding them: so you went before your people, to make yourself a great name.", "geneva": "As the beast goeth downe into the valley, the Spirite of the Lord gaue them rest: so diddest thou leade thy people, to make thy selfe a glorious Name.", "wycliffe": "as a beeste goynge doun in the feeld? The Spirit of the Lord was the ledere therof; so thou leddist thi puple, that thou madist to thee a name of glorie.", "rotherham": "As a beast, into the valley, goeth down, The Spirit of Yahweh, causeth him to rest, So, didst thou lead thy people, To make thyself a majestic name!", "darby": "As cattle go down into the valley, the Spirit of Jehovah gave them rest; so didst thou lead thy people, to make thyself a glorious name.", "twenty": "", "jps": "As the cattle that go down into the valley, the spirit of HaShem caused them to rest; so didst Thou lead Thy people, to make Thyself a glorious name.'", "acv": "As the cattle that go down into the valley, the Spirit of Jehovah caused them to rest. So thou led thy people to make thyself a glorious name.", "anderson": "", "haweis": "", "noyes": "As the herd descendeth into the valley, The spirit of Jehovah led them to rest. So didst thou lead thy people, To make for thyself a glorious name.", "webster": "As a beast goeth down in the valley, the Spirit of the LORD caused him to rest: so didst thou lead thy people, to make thyself a glorious name.", "vulgate": "quasi animal in campo descendens spiritus Domini ductor eius fuit sic adduxisti populum tuum ut faceres tibi nomen gloriae;", "brenton": "and as cattle through a plain: the Spirit came down from the Lord, and guided them: thus thou leddest thy people, to make thyself a glorious name."}}, {"v": 15, "ref": "63:15", "o": "הַבֵּ֤ט מִ/שָּׁמַ֨יִם֙ וּ/רְאֵ֔ה מִ/זְּבֻ֥ל קָדְשְׁ/ךָ֖ וְ/תִפְאַרְתֶּ֑/ךָ אַיֵּ֤ה קִנְאָֽתְ/ךָ֙ וּ/גְב֣וּרֹתֶ֔/ךָ הֲמ֥וֹן מֵעֶ֛י/ךָ וְֽ/רַחֲמֶ֖י/ךָ אֵלַ֥/י הִתְאַפָּֽקוּ", "en": {"kjv": "Look down from heaven, and behold from the habitation of thy holiness and of thy glory: where is thy zeal and thy strength, the sounding of thy bowels and of thy mercies toward me? are they restrained?", "web": "Look down from heaven, and see from the habitation of your holiness and of your glory: where are your zeal and your mighty acts? the yearning of your heart and your compassion is restrained toward me.", "bsb": "Look down from heaven and see, from Your holy and glorious habitation. Where are Your zeal and might? Your yearning and compassion for me are restrained.", "asv": "Look down from heaven, and behold from the habitation of thy holiness and of thy glory: where are thy zeal and thy mighty acts? the yearning of thy heart and thy compassions are restrained toward me.", "ylt": "Look attentively from the heavens, And see from Thy holy and beauteous habitation, Where is Thy zeal and Thy might? The multitude of Thy bowels and Thy mercies Towards me have refrained themselves.", "dra": "Look down from heaven, and behold from thy holy habitation and the place of thy glory: where is thy zeal, and thy strength, the multitude of thy bowels, and of thy mercies? they have held back themselves from me.", "bbe": "Let your eyes be looking down from heaven, from your holy and beautiful house: where is your deep feeling, the working of your power? do not keep back the moving of your pity and your mercies:", "geneva": "Looke downe from heauen, and beholde from the dwelling place of thine holines, and of thy glory. Where is thy zeale and thy strength, the multitude of thy mercies, and of thy compassions? they are restrained from me.", "wycliffe": "Biholde thou fro heuene, and se fro thin hooli dwellyng place, and fro the seete of thi glorie. Where is thi feruent loue, and thi strengthe, the multitude of thin entrailis, and of thi merciful doyngis?", "rotherham": "Look thou down, out of the heavens and see, Out of the high abode of thy holiness and of thy majesty,—Where are thy jealousy, and thy mighty deeds? The resounding of thy yearning affection, and thy compassions towards me, are they restrained?", "darby": "Look down from the heavens, and behold from the habitation of thy holiness and of thy glory! Where is thy zeal and thy strength, the sounding of thy bowels and of thy tender mercies? Are they restrained toward me?", "twenty": "", "jps": "Look down from heaven, and see, even from Thy holy and glorious habitation; where is Thy zeal and Thy mighty acts, the yearning of Thy heart and Thy compassions, now restrained toward me?", "acv": "Look down from heaven, and behold from the habitation of thy holiness and of thy glory. Where are thy zeal and thy mighty acts? The yearning of thy heart and thy compassions are restrained toward me.", "anderson": "", "haweis": "", "noyes": "Look down from heaven, and behold from thy holy and glorious habitation! Where is thy zeal and thy might? Thy pity and compassion for me, are they restrained?", "webster": "Look down from heaven, and behold from the habitation of thy holiness and of thy glory: where [is] thy zeal and thy strength, the sounding of thy bowels and of thy mercies towards me? are they restrained?", "vulgate": "adtende de caelo et vide de habitaculo sancto tuo et gloriae tuae ubi est zelus tuus et fortitudo tua multitudo viscerum tuorum et miserationum tuarum super me continuerunt se;", "brenton": "Turn from heaven, and look from thy holy habitation and from thy glory: where is thy zeal and thy strength? where is the abundance of thy mercy and of thy compassions, that thou hast withholden thyself from us?"}}, {"v": 16, "ref": "63:16", "o": "כִּֽי אַתָּ֣ה אָבִ֔י/נוּ כִּ֤י אַבְרָהָם֙ לֹ֣א יְדָעָ֔/נוּ וְ/יִשְׂרָאֵ֖ל לֹ֣א יַכִּירָ֑/נוּ אַתָּ֤ה יְהוָה֙ אָבִ֔י/נוּ גֹּאֲלֵ֥/נוּ מֵֽ/עוֹלָ֖ם שְׁמֶֽ/ךָ", "en": {"kjv": "Doubtless thou art our father, though Abraham be ignorant of us, and Israel acknowledge us not: thou, O Lord, art our father, our redeemer; thy name is from everlasting.", "web": "For you are our Father, though Abraham doesn’t know us, and Israel does not acknowledge us: you, Yahweh, are our Father; our Redeemer from everlasting is your name.", "bsb": "Yet You are our Father, though Abraham does not know us and Israel does not acknowledge us. You, O LORD, are our Father; our Redeemer from Everlasting is Your name.", "asv": "For thou art our Father, though Abraham knoweth us not, and Israel doth not acknowledge us: thou, O Jehovah, art our Father; our Redeemer from everlasting is thy name.", "ylt": "For Thou art our Father, For Abraham hath not known us, And Israel doth not acknowledge us, Thou, O Jehovah, art our Father, Our redeemer from the age, is Thy name.", "dra": "For thou art our father, and Abraham hath not known us, and Israel hath been ignorant of us: thou, O Lord, art our father, our redeemer, from everlasting is thy name.", "bbe": "For you are our father, though Abraham has no knowledge of us, and Israel gives no thought to us: you, O Lord, are our father; from the earliest days you have taken up our cause.", "geneva": "Doutles thou art our Father: though Abraham be ignorant of vs, and Israel knowe vs not, yet thou, O Lord, art our Father, and our redeemer: thy Name is for euer.", "wycliffe": "Tho withelden hem silf on me. Forsothe thou art oure fadir, and Abraham knew not vs, and Israel knew not vs.", "rotherham": "For, thou, art our father, Though, Abraham, knew us not, And Israel could not acknowledge us,—Thou, O Yahweh, art our father, Our Redeemer from the Age-past time, is thy name.", "darby": "For thou art our Father, though Abraham be ignorant of us, and Israel acknowledge us not: thou, Jehovah, art our Father; our Redeemer, from everlasting, is thy name.", "twenty": "", "jps": "For Thou art our Father; for Abraham knoweth us not, and Israel doth not acknowledge us; Thou, O HaShem, art our Father, our Redeemer from everlasting is Thy name.", "acv": "For thou are our Father, though Abraham knows us not, and Israel does not acknowledge us, thou, O Jehovah, are our Father, our Redeemer, from everlasting is thy name.", "anderson": "", "haweis": "", "noyes": "Thou, surely, art our father; Abraham is ignorant of us, And Israel knoweth us not. Thou, O Jehovah, art our father; Our deliverer wast thou of old.", "webster": "Doubtless thou [art] our father, though Abraham be ignorant of us, and Israel acknowledge us not: thou, O LORD, [art] our father, our Redeemer; thy name [is] from everlasting.", "vulgate": "tu enim pater noster et Abraham nescivit nos et Israhel ignoravit nos tu Domine pater noster redemptor noster a saeculo nomen tuum;", "brenton": "For thou art our Father; for though Abraham knew us not, and Israel did not acknowledge us, yet do thou, O Lord, our Father, deliver us: thy name has been upon us from the beginning."}}, {"v": 17, "ref": "63:17", "o": "לָ֣/מָּה תַתְעֵ֤/נוּ יְהוָה֙ מִ/דְּרָכֶ֔י/ךָ תַּקְשִׁ֥יחַ לִבֵּ֖/נוּ מִ/יִּרְאָתֶ֑/ךָ שׁ֚וּב לְמַ֣עַן עֲבָדֶ֔י/ךָ שִׁבְטֵ֖י נַחֲלָתֶֽ/ךָ", "en": {"kjv": "O Lord, why hast thou made us to err from thy ways, and hardened our heart from thy fear? Return for thy servants’ sake, the tribes of thine inheritance.", "web": "O Yahweh, why do you make us to err from your ways, and harden our heart from your fear? Return for your servants’ sake, the tribes of your inheritance.", "bsb": "Why, O LORD, do You make us stray from Your ways and harden our hearts from fearing You? Return, for the sake of Your servants, the tribes of Your heritage.", "asv": "O Jehovah, why dost thou make us to err from thy ways, and hardenest our heart from thy fear? Return for thy servants’ sake, the tribes of thine inheritance.", "ylt": "Why causest Thou us to wander, O Jehovah, from Thy ways? Thou hardenest our heart from Thy fear, Turn back for Thy servants' sake, The tribes of Thine inheritance.", "dra": "Why hast thou made us to err, O Lord, from thy ways: why hast thou hardened our heart, that we should not fear thee? return for the sake of thy servants, the tribes of thy inheritance.", "bbe": "O Lord, why do you send us wandering from your ways, making our hearts hard, so that we have no fear of you? Come back, because of your servants, the tribes of your heritage.", "geneva": "O Lord, why hast thou made vs to erre from thy wayes? and hardened our heart from thy feare? Returne for thy seruants sake, and for the tribes of thine inheritance.", "wycliffe": "Thou, Lord, art oure fadir, and oure ayenbiere; thi name is fro the world. Lord, whi hast thou maad vs to erre fro thi weies? thou hast made hard oure herte, that we dredden not thee? be thou conuertid, for thi seruauntis, the lynages of thin eritage.", "rotherham": "Wherefore shouldst thou suffer us to wander O Yahweh, from thy ways? Wherefore shouldst thou let us harden our heart past revering thee? Return thou for the sake of Thy servants, The tribes thou thyself hast inherited.", "darby": "Why, O Jehovah, hast thou made us to err from thy ways, hast hardened our heart from thy fear? Return for thy servants' sake, the tribes of thine inheritance.", "twenty": "", "jps": "O HaShem, why dost Thou make us to err from Thy ways, and hardenest our heart from Thy fear? Return for Thy servants' sake, the tribes of Thine inheritance.", "acv": "O Jehovah, why do thou make us to err from thy ways, and harden our heart from thy fear? Return for thy servants' sake, the tribes of thine inheritance.", "anderson": "", "haweis": "", "noyes": "Why, O Jehovah, dost thou suffer us to wander from thy ways, And harden our hearts against thy fear? Return, for thy servants’ sake, The tribes of thine inheritance!", "webster": "O LORD, why hast thou made us to err from thy ways, [and] hardened our heart from thy fear? Return for thy servants' sake, the tribes of thy inheritance.", "vulgate": "quare errare nos fecisti Domine de viis tuis indurasti cor nostrum ne timeremus te convertere propter servos tuos tribus hereditatis tuae;", "brenton": "Why hast thou caused us to err, O Lord, from thy way? and has hardened our hearts, that we should not fear thee? Return for thy servants' sake, for the sake of the tribes of thine inheritance,"}}, {"v": 18, "ref": "63:18", "o": "לַ/מִּצְעָ֕ר יָרְשׁ֖וּ עַם קָדְשֶׁ֑/ךָ צָרֵ֕י/נוּ בּוֹסְס֖וּ מִקְדָּשֶֽׁ/ךָ", "en": {"kjv": "The people of thy holiness have possessed it but a little while: our adversaries have trodden down thy sanctuary.", "web": "Your holy people possessed it but a little while: our adversaries have trodden down your sanctuary.", "bsb": "For a short while Your people possessed Your holy place, but our enemies have trampled Your sanctuary.", "asv": "Thy holy people possessed it but a little while: our adversaries have trodden down thy sanctuary.", "ylt": "For a little while did Thy holy people possess, Our adversaries have trodden down Thy sanctuary.", "dra": "They have possessed thy holy people as nothing: our enemies have trodden down thy sanctuary.", "bbe": "Why have evil men gone over your holy place, so that it has been crushed under the feet of our haters?", "geneva": "The people of thine holinesse haue possessed it, but a litle while: for our aduersaries haue troden downe thy Sanctuarie.", "wycliffe": "Thei hadden as nouyt thin hooli puple in possessioun, and oure enemyes defouliden thin halewyng.", "rotherham": "For a short time only, did thy holy people hold possession,—Our adversaries, trod down thy sanctuary!", "darby": "Thy holy people have possessed [it] but a little while: our adversaries have trodden down thy sanctuary.", "twenty": "", "jps": "Thy holy people they have well nigh driven out, our adversaries have trodden down Thy sanctuary.", "acv": "Thy holy people possessed it but a little while. Our adversaries have trodden down thy sanctuary.", "anderson": "", "haweis": "", "noyes": "But a little while did thy holy people possess the land; Then our enemies trampled upon thy sanctuary.", "webster": "The people of thy holiness have possessed [it] but a little while: our adversaries have trodden down thy sanctuary.", "vulgate": "quasi nihilum possederunt populum sanctum tuum hostes nostri conculcaverunt sanctificationem tuam;", "brenton": "that we may inherit a small part of thy holy mountain."}}, {"v": 19, "ref": "63:19", "o": "הָיִ֗ינוּ מֵֽ/עוֹלָם֙ לֹֽא מָשַׁ֣לְתָּ בָּ֔/ם לֹֽא נִקְרָ֥א שִׁמְ/ךָ֖ עֲלֵי/הֶ֑ם לוּא קָרַ֤עְתָּ שָׁמַ֨יִם֙ יָרַ֔דְתָּ מִ/פָּנֶ֖י/ךָ הָרִ֥ים נָזֹֽלּוּ", "en": {"kjv": "We are thine: thou never barest rule over them; they were not called by thy name.", "web": "We have become as they over whom you never bear rule, as those who were not called by your name.", "bsb": "We have become like those You never ruled, like those not called by Your name.", "asv": "We are become as they over whom thou never barest rule, as they that were not called by thy name.", "ylt": "We have been from of old, Thou hast not ruled over them, Not called is Thy name upon them!", "dra": "We are become as in the beginning, when thou didst not rule over us, and when we were not called by thy name.", "bbe": "We have become as those who were never ruled by you, on whom your name was not named.", "geneva": "We haue bene as they, ouer whome thou neuer barest rule, and vpon whom thy Name was not called.", "wycliffe": "We ben maad as in the bigynnyng, whanne thou were not Lord of vs, nethir thi name was clepid to help on vs.", "rotherham": "We have become like those Over whom from age-past times, thou hast not ruled, Who have never been called by thy name!", "darby": "We have become [like those] over whom thou never barest rule, those not called by thy name.", "twenty": "", "jps": "We are become as they over whom Thou never borest rule, as they that were not called by Thy name. Oh, that Thou wouldest rend the heavens, that Thou wouldest come down, that the mountains might quake at Thy presence.", "acv": "We have become as those over whom thou never bore rule, as those who were not called by thy name.", "anderson": "", "haweis": "", "noyes": "It has been with us as if thou hadst never ruled over us, As if we had not been called by thy name.", "webster": "We are [thine]: thou never didst bear rule over them; they were not called by thy name.", "vulgate": "facti sumus quasi in principio cum non dominareris nostri neque invocaretur nomen tuum super nos;", "brenton": "We are become as at the beginning, when thou didst not rule over us, and thy name was not called upon us."}}]}, {"c": 64, "verses": [{"v": 1, "ref": "64:1", "o": "כִּ/קְדֹ֧חַ אֵ֣שׁ הֲמָסִ֗ים מַ֚יִם תִּבְעֶה אֵ֔שׁ לְ/הוֹדִ֥יעַ שִׁמְ/ךָ֖ לְ/צָרֶ֑י/ךָ מִ/פָּנֶ֖י/ךָ גּוֹיִ֥ם יִרְגָּֽזוּ", "en": {"kjv": "Oh that thou wouldest rend the heavens, that thou wouldest come down, that the mountains might flow down at thy presence,", "web": "Oh that you would tear the heavens, that you would come down, that the mountains might quake at your presence,", "bsb": "If only You would rend the heavens and come down, so that mountains would quake at Your presence,", "asv": "Oh that thou wouldest rend the heavens, that thou wouldest come down, that the mountains might quake at thy presence,", "ylt": "Didst Thou not rend the heavens? Thou didst come down, From thy presence did mountains flow,", "dra": "O that thou wouldst rend the heavens, and wouldst come down: the mountains would melt away at thy presence.", "bbe": "O let the heavens be broken open and come down, so that the mountains may be shaking before you,", "geneva": "Oh, that thou wouldest breake the heauens, and come downe, and that the mountaines might melt at thy presence!", "wycliffe": "I wolde that thou brakist heuenes, and camest doun, that hillis fletiden awei fro thi face,", "rotherham": "Would that thou hadst rent the heavens, hadst come down,", "darby": "Oh, that thou wouldest rend the heavens, that thou wouldest come down, — that the mountains might flow down at thy presence,", "twenty": "", "jps": "As when fire kindleth the brush-wood, and the fire causeth the waters to boil; to make Thy name known to Thine adversaries, that the nations might tremble at Thy presence,", "acv": "Oh that thou would rend the heavens, that thou would come down, that the mountains might quake at thy presence,", "anderson": "", "haweis": "", "noyes": "O that thou wouldst rend the heavens, and come down; That the mountains might tremble at thy presence,", "webster": "Oh that thou wouldst rend the heavens, that thou wouldst come down, that the mountains might flow down at thy presence,", "vulgate": "utinam disrumperes caelos et descenderes a facie tua montes defluerent;", "brenton": "If thou wouldest open the heaven, trembling will take hold upon the mountains from thee, and they shall melt,"}}, {"v": 2, "ref": "64:2", "o": "בַּ/עֲשׂוֹתְ/ךָ֥ נוֹרָא֖וֹת לֹ֣א נְקַוֶּ֑ה יָרַ֕דְתָּ מִ/פָּנֶ֖י/ךָ הָרִ֥ים נָזֹֽלּוּ", "en": {"kjv": "As when the melting fire burneth, the fire causeth the waters to boil, to make thy name known to thine adversaries, that the nations may tremble at thy presence!", "web": "as when fire kindles the brushwood, and the fire causes the waters to boil; to make your name known to your adversaries, that the nations may tremble at your presence!", "bsb": "as fire kindles the brushwood and causes the water to boil, to make Your name known to Your enemies, so that the nations will tremble at Your presence!", "asv": "as when fire kindleth the brushwood, and the fire causeth the waters to boil; to make thy name known to thine adversaries, that the nations may tremble at thy presence!", "ylt": "(As fire kindleth stubble--Fire causeth water to boil,) To make known Thy name to Thine adversaries, From Thy presence do nations tremble.", "dra": "They would melt as at the burning of fire, the waters would burn with fire, that thy name might be made known to thy enemies: that the nations might tremble at thy presence.", "bbe": "As when fire puts the brushwood in flames, or as when water is boiling from the heat of the fire: to make your name feared by your haters, so that the nations may be shaking before you;", "geneva": "As the melting fire burned, as the fire caused the waters to boyle, (that thou mightest declare thy Name to thy aduersaries) the people did tremble at thy presence.", "wycliffe": "and failiden as brennyng of fier, and brente in fier; that thi name were made knowun to thin enemyes, and folkis weren disturblid of thi face.", "rotherham": "At thy presence, had mountains, quaked: As fire kindleth brushwood, [As] fire causeth, water, to boil, So if thou wouldst make known thy Name to thine adversaries, At thy presence, nations, would tremble.", "darby": "— as fire kindleth brushwood, as the fire causeth water to boil, to make thy name known to thine adversaries, that the nations might tremble at thy presence!", "twenty": "", "jps": "When Thou didst tremendous things which we looked not for--Oh that Thou wouldest come down, that the mountains might quake at Thy presence!--", "acv": "as when fire kindles the brushwood, and the fire causes the waters to boil, to make thy name known to thine adversaries, that the nations may tremble at thy presence!", "anderson": "", "haweis": "", "noyes": "As fire kindleth the dry stubble, As fire causeth water to boil, To make known thy name to thine adversaries, That the nations might tremble at thy presence;", "webster": "[As when] the melting fire burneth, the fire causeth the waters to boil, to make thy name known to thy adversaries, [that] the nations may tremble at thy presence!", "vulgate": "sicut exustio ignis tabescerent aquae arderent igni ut notum fieret nomen tuum inimicis tuis a facie tua gentes turbarentur;", "brenton": "as wax melts before the fire; and fire shall burn up the enemies, and thy name shall be manifest among the adversaries: at thy presence the nations shall be troubled,"}}, {"v": 3, "ref": "64:3", "o": "וּ/מֵ/עוֹלָ֥ם לֹא שָׁמְע֖וּ לֹ֣א הֶאֱזִ֑ינוּ עַ֣יִן לֹֽא רָאָ֗תָה אֱלֹהִים֙ זוּלָ֣תְ/ךָ֔ יַעֲשֶׂ֖ה לִ/מְחַכֵּה לֽ/וֹ", "en": {"kjv": "When thou didst terrible things which we looked not for, thou camest down, the mountains flowed down at thy presence.", "web": "When you did awesome things which we didn’t look for, you came down, the mountains quaked at your presence.", "bsb": "When You did awesome works that we did not expect, You came down, and the mountains trembled at Your presence.", "asv": "When thou didst terrible things which we looked not for, thou camest down, the mountains quaked at thy presence.", "ylt": "In Thy doing fearful things--we expect not, Thou didst come down, From Thy presence did mountains flow.", "dra": "When thou shalt do wonderful things, we shall not bear them: thou didst come down, and at thy presence the mountains melted away.", "bbe": "While you do acts of power for which we are not looking, and which have not come to the ears of men in the past.", "geneva": "When thou diddest terrible things, which we looked not for, thou camest downe, and the mountaines melted at thy presence.", "wycliffe": "Whanne thou schalt do merueils, we schulen not abide. Thou camest doun, and hillis fletiden awei fro thi face.", "rotherham": "When thou didst fearful things we could not expect, Thou camest down at thy presence, mountains, quaked.", "darby": "When thou didst terrible things [which] we looked not for, thou camest down, and the mountains flowed down at thy presence.", "twenty": "", "jps": "And whereof from of old men have not heard, nor perceived by the ear, neither hath the eye seen a G-d beside Thee, who worketh for him that waiteth for Him.", "acv": "When thou did fearful things which we did not look for, thou came down; the mountains quaked at thy presence.", "anderson": "", "haweis": "", "noyes": "As thou once didst wonderful things, which we looked not for, And camest down, so that the mountains trembled at thy presence.", "webster": "When thou didst terrible things [which] we looked not for, thou camest down, the mountains flowed down at thy presence.", "vulgate": "cum feceris mirabilia non sustinebimus descendisti et a facie tua montes defluxerunt;", "brenton": "whenever thou shalt work gloriously; trembling from thee shall take hold upon the mountains."}}, {"v": 4, "ref": "64:4", "o": "פָּגַ֤עְתָּ אֶת שָׂשׂ֙ וְ/עֹ֣שֵׂה צֶ֔דֶק בִּ/דְרָכֶ֖י/ךָ יִזְכְּר֑וּ/ךָ הֵן אַתָּ֤ה קָצַ֨פְתָּ֙ וַֽ/נֶּחֱטָ֔א בָּ/הֶ֥ם עוֹלָ֖ם וְ/נִוָּשֵֽׁעַ", "en": {"kjv": "For since the beginning of the world men have not heard, nor perceived by the ear, neither hath the eye seen, O God, beside thee, what he hath prepared for him that waiteth for him.", "web": "For from of old men have not heard, nor perceived by the ear, neither has the eye seen a God besides you, who works for him who waits for him.", "bsb": "From ancient times no one has heard, no ear has perceived, no eye has seen any God besides You, who acts on behalf of those who wait for Him.", "asv": "For from of old men have not heard, nor perceived by the ear, neither hath the eye seen a God besides thee, who worketh for him that waiteth for him.", "ylt": "Even from antiquity men have not heard, They have not given ear, Eye hath not seen a God save Thee, He doth work for those waiting for Him.", "dra": "From the beginning of the world they have not heard, nor perceived with the ears: the eye hath not seen, O God, besides thee, what things thou hast prepared for them that wait for thee.", "bbe": "The ear has not had news of, or the eye seen, ... any God but you, working for the man who is waiting for him.", "geneva": "For since the beginning of the world they haue not heard nor vnderstande with the eare, neither hath ye eye seene another God beside thee, which doeth so to him that waiteth for him.", "wycliffe": "Fro the world thei herden not, nethir perseyueden with eeris; God, non iye siy, withouten thee, what thingis thou hast maad redi to hem that abiden thee.", "rotherham": "Although from age-past times It was never heard, It was not perceived by the ear,—Neither did, the eye, ever see—That, a god besides thee, could work for the man who waited for him,", "darby": "Never have [men] heard, nor perceived by the ear, nor hath eye seen aGod beside thee, who acteth for him that waiteth for him.", "twenty": "", "jps": "Thou didst take away him that joyfully worked righteousness, those that remembered Thee in Thy ways--behold, Thou wast wroth, and we sinned--upon them have we stayed of old, that we might be saved.", "acv": "For from of old men have not heard, nor perceived by the ear, neither has the eye seen, O God, besides thee, what he has prepared for him who waits for him.", "anderson": "", "haweis": "", "noyes": "For never have men heard, nor perceived by the ear, Nor hath eye seen, a God beside thee. Who doeth such things for those that trust in him.", "webster": "For since the beginning of the world [men] have not heard, nor perceived by the ear, neither hath the eye seen, O God, besides thee, [what] he hath prepared for him that waiteth for him.", "vulgate": "a saeculo non audierunt neque auribus perceperunt oculus non vidit Deus absque te quae praeparasti expectantibus te;", "brenton": "From of old we have not heard, neither have our eyes seen a God beside thee, and thy works which thou wilt perform to them that wait for mercy."}}, {"v": 5, "ref": "64:5", "o": "וַ/נְּהִ֤י כַ/טָּמֵא֙ כֻּלָּ֔/נוּ וּ/כְ/בֶ֥גֶד עִדִּ֖ים כָּל צִדְקֹתֵ֑י/נוּ וַ/נָּ֤בֶל כֶּֽ/עָלֶה֙ כֻּלָּ֔/נוּ וַ/עֲוֺנֵ֖/נוּ כָּ/ר֥וּחַ יִשָּׂאֻֽ/נוּ", "en": {"kjv": "Thou meetest him that rejoiceth and worketh righteousness, those that remember thee in thy ways: behold, thou art wroth; for we have sinned: in those is continuance, and we shall be saved.", "web": "You meet him who rejoices and works righteousness, those who remember you in your ways. Behold, you were angry, and we sinned. We have been in sin for a long time; and shall we be saved?", "bsb": "You welcome those who gladly do right, who remember Your ways. Surely You were angry, for we sinned. How can we be saved if we remain in our sins?", "asv": "Thou meetest him that rejoiceth and worketh righteousness, those that remember thee in thy ways: behold, thou wast wroth, and we sinned: in them have we been of long time; and shall we be saved?", "ylt": "Thou hast met with the rejoicer And the doer of righteousness, In Thy ways they remember Thee, Lo, Thou hast been wroth when we sin, By them is continuance, and we are saved.", "dra": "Thou hast met him that rejoiceth, and doth justice: in thy ways they shall remember thee: behold thou art angry, and we have sinned: in them we have been always, and we shall be saved.", "bbe": "Will you not have mercy on him who takes pleasure in doing righteousness, even on those who keep in mind your ways? Truly you were angry, and we went on doing evil, and sinning against you in the past.", "geneva": "Thou diddest meete him, that reioyced in thee, and did iustly: they remembred thee in thy wayes: beholde, thou art angrie, for we haue sinned: yet in them is continuance, and we shall be saued.", "wycliffe": "Thou mettist hym that is glad, and doith riytfulnesse; in thi weies thei schulen bithenke on thee. Lo! thou art wrooth, and we synneden; in tho synnes we weren euere, and we schulen be saued.", "rotherham": "Yet didst thou meet Him who was rejoicing and working righteousness, Even them who in thy ways, remembered thee,—Lo! thou, hast been vexed, And truly we had sinned, Among them, was the prospect of an age [to come], That we might be saved.", "darby": "Thou meetest him that rejoiceth to do righteousness, those that remember thee in thy ways: (behold, thou wast wroth, and we have sinned:) in those is perpetuity, and we shall be saved.", "twenty": "", "jps": "And we are all become as one that is unclean, and all our righteousnesses are as a polluted garment; and we all do fade as a leaf, and our iniquities, like the wind, take us away.", "acv": "Thou meet him who rejoices and works righteousness, those who remember thee in thy ways. Behold, thou were angry, and we sinned. Therefore we have erred.", "anderson": "", "haweis": "", "noyes": "Thou art the friend of those who joyfully do righteousness, Those who remember thee in thy ways. Behold, thou art angry, and we are punished; Long doth the punishment endure, before we are delivered.", "webster": "Thou meetest him that rejoiceth, and worketh righteousness, [those that] remember thee in thy ways: behold, thou art wroth; for we have sinned: in those is continuance, and we shall be saved.", "vulgate": "occurristi laetanti et facienti iustitiam in viis tuis recordabuntur tui ecce tu iratus es et peccavimus in ipsis fuimus semper et salvabimur;", "brenton": "For these blessings shall happen to them that work righteousness, and they shall remember thy ways: behold, thou wast angry and we have sinned; therefore we have erred,"}}, {"v": 6, "ref": "64:6", "o": "וְ/אֵין קוֹרֵ֣א בְ/שִׁמְ/ךָ֔ מִתְעוֹרֵ֖ר לְ/הַחֲזִ֣יק בָּ֑/ךְ כִּֽי הִסְתַּ֤רְתָּ פָנֶ֨י/ךָ֙ מִמֶּ֔/נּוּ וַ/תְּמוּגֵ֖/נוּ בְּ/יַד עֲוֺנֵֽ/נוּ", "en": {"kjv": "But we are all as an unclean thing, and all our righteousnesses are as filthy rags; and we all do fade as a leaf; and our iniquities, like the wind, have taken us away.", "web": "For we have all become as one who is unclean, and all our righteousness is as a polluted garment: and we all fade as a leaf; and our iniquities, like the wind, take us away.", "bsb": "Each of us has become like something unclean, and all our righteous acts are like filthy rags; we all wither like a leaf, and our iniquities carry us away like the wind.", "asv": "For we are all become as one that is unclean, and all our righteousnesses are as a polluted garment: and we all do fade as a leaf; and our iniquities, like the wind, take us away.", "ylt": "And we are as unclean--all of us, And as a garment passing away, all our righteous acts; And we fade as a leaf--all of us. And our iniquities as wind do take us away.", "dra": "And we are all become as one unclean, and all our justices as the rag of a menstruous woman: and we have all fallen as a leaf, and our iniquities, like the wind, have taken us away.", "bbe": "For we have all become like an unclean person, and all our good acts are like a dirty robe: and we have all become old like a dead leaf, and our sins, like the wind, take us away.", "geneva": "But we haue all bene as an vncleane thing, and all our righteousnes is as filthie cloutes, and we all doe fade like a leafe, and our iniquities like the winde haue taken vs away.", "wycliffe": "And alle we ben maad as an vncleene man; alle oure riytfulnessis ben as the cloth of a womman in vncleene blood; and alle we fellen doun as a leef, and our wickidnessis as wynd han take awei vs.", "rotherham": "But we have become as one unclean all of us, And, as a garment polluted, were all our righteous doings,—And so we faded like a leaf all of us, And, our iniquity, as a wind, carried us away;", "darby": "And we are all become as an unclean [thing], and all our righteousnesses are as filthy rags; and we all fade as a leaf, and our iniquities, like the wind, have carried us away;", "twenty": "", "jps": "And there is none that calleth upon Thy name, that stirreth up himself to take hold of Thee; for Thou hast hid Thy face from us, and hast consumed us by means of our iniquities.", "acv": "For we have all become as unclean, and all our righteous acts are as a polluted garment. And we all fade as a leaf. And our iniquities, like the wind, take us away.", "anderson": "", "haweis": "", "noyes": "We are all of us an unclean thing; Like a filthy garment is all our righteousness; We are all withered like a leaf, And our sins, like a storm, have blown us away.", "webster": "But we are all as an unclean [thing], and all our righteousnesses [are] as filthy rags; and we all do fade as a leaf; and our iniquities, like the wind, have taken us away.", "vulgate": "et facti sumus ut inmundus omnes nos quasi pannus menstruatae universae iustitiae nostrae et cecidimus quasi folium universi et iniquitates nostrae quasi ventus abstulerunt nos;", "brenton": "and we are all become as unclean, and all our righteousness as a filthy rag: and we have fallen as leaves because of our iniquities; thus the wind shall carry us away."}}, {"v": 7, "ref": "64:7", "o": "וְ/עַתָּ֥ה יְהוָ֖ה אָבִ֣י/נוּ אָ֑תָּה אֲנַ֤חְנוּ הַ/חֹ֨מֶר֙ וְ/אַתָּ֣ה יֹצְרֵ֔/נוּ וּ/מַעֲשֵׂ֥ה יָדְ/ךָ֖ כֻּלָּֽ/נוּ", "en": {"kjv": "And there is none that calleth upon thy name, that stirreth up himself to take hold of thee: for thou hast hid thy face from us, and hast consumed us, because of our iniquities.", "web": "There is no one who calls on your name, who stirs up himself to take hold of you; for you have hidden your face from us, and have consumed us by means of our iniquities.", "bsb": "No one calls on Your name or strives to take hold of You. For You have hidden Your face from us and delivered us into the hand of our iniquity.", "asv": "And there is none that calleth upon thy name, that stirreth up himself to take hold of thee; for thou hast hid thy face from us, and hast consumed us by means of our iniquities.", "ylt": "And there is none calling in Thy name, Stirring up himself to lay hold on Thee, For Thou hast hid Thy face from us, And thou meltest us away by our iniquities.", "dra": "There is none that calleth upon thy name: that riseth up, and taketh hold of thee: thou hast hid thy face from us, and hast crushed us in the hand of our iniquity.", "bbe": "And there is no one who makes prayer to your name, or who is moved to keep true to you: for your face is veiled from us, and you have given us into the power of our sins.", "geneva": "And there is none that calleth vpon thy Name, neither that stirreth vp himselfe to take holde of thee: for thou hast hid thy face from vs, and hast consumed vs because of our iniquities.", "wycliffe": "Noon is, that clepith thi name to help, that risith, and holdith thee; thou hast hid thi face fro vs, and thou hast hurtlid doun vs in the hond of oure wickidnesse.", "rotherham": "And there was none To call upon thy Name, To rouse himself to lay firm hold on thee,—For thou hadst hidden thy face from us, And hadst made us despond, by means of our iniquity.", "darby": "and there is none that calleth upon thy name, that stirreth up himself to take hold of thee; for thou hast hidden thy face from us, and hast caused us to melt away through our iniquities.", "twenty": "", "jps": "But now, O HaShem, Thou art our Father; we are the clay, and Thou our potter, and we all are the work of Thy hand.", "acv": "And there is none who calls upon thy name, who stirs himself up to take hold of thee. For thou have hid thy face from us, and have consumed us through our iniquities.", "anderson": "", "haweis": "", "noyes": "There is none that calleth upon thy name, That stirreth himself up to cleave to thee; For thou hidest thy face from us, And lettest us perish by our iniquities.", "webster": "And [there is] none that calleth upon thy name, that stirreth up himself to take hold of thee: for thou hast hid thy face from us, and hast consumed us, because of our iniquities.", "vulgate": "non est qui invocet nomen tuum qui consurgat et teneat te abscondisti faciem tuam a nobis et adlisisti nos in manu iniquitatis nostrae;", "brenton": "And there is none that calls upon thy name, or that remembers to take hold on thee: for thou hast turned thy face away from us, and hast delivered us up because of our sins."}}, {"v": 8, "ref": "64:8", "o": "אַל תִּקְצֹ֤ף יְהוָה֙ עַד מְאֹ֔ד וְ/אַל לָ/עַ֖ד תִּזְכֹּ֣ר עָוֺ֑ן הֵ֥ן הַבֶּט נָ֖א עַמְּ/ךָ֥ כֻלָּֽ/נוּ", "en": {"kjv": "But now, O Lord, thou art our father; we are the clay, and thou our potter; and we all are the work of thy hand.", "web": "But now, Yahweh, you are our Father; we are the clay, and you our potter; and we all are the work of your hand.", "bsb": "But now, O LORD, You are our Father; we are the clay, and You are the potter; we are all the work of Your hand.", "asv": "But now, O Jehovah, thou art our Father; we are the clay, and thou our potter; and we all are the work of thy hand.", "ylt": "And now, O Jehovah, thou art our Father, We are the clay, and Thou our Framer, And the work of Thy hand--all of us.", "dra": "And now, O Lord, thou art our father, and we are clay: and thou art our maker, and we all are the works of thy hands.", "bbe": "But now, O Lord, you are our father; we are the earth, and you are our maker; and we are all the work of your hand.", "geneva": "But now, O Lord, thou art our Father: we are the clay, and thou art our potter, and we all are the worke of thine hands.", "wycliffe": "And now, Lord, thou art oure fadir; forsothe we ben cley, and thou art oure maker, and alle we ben the werkis of thin hondis.", "rotherham": "But, now, O Yahweh, our father, thou art,—We are the clay, and, thou, art our potter, Yea the work of thy hand, are we all:", "darby": "And now, Jehovah, thou art our Father; we are the clay, and thou our potter; and we all are the work of thy hand.", "twenty": "", "jps": "Be not wroth very sore, O HaShem, neither remember iniquity for ever; behold, look, we beseech Thee, we are all Thy people.", "acv": "But now, O Jehovah, thou are our Father. We are the clay, and thou our potter, and we are all the work of thy hand.", "anderson": "", "haweis": "", "noyes": "But now, O Jehovah, thou art our father; We are the clay, and thou hast formed us; We are all of us the work of thy hands.", "webster": "But now, O LORD, thou [art] our father; we [are] the clay, and thou our potter; and we all [are] the work of thy hand.", "vulgate": "et nunc Domine pater noster es tu nos vero lutum et fictor noster et opera manuum tuarum omnes nos;", "brenton": "And now, O Lord, thou art our Father, and we are clay, all of us the work of thine hands."}}, {"v": 9, "ref": "64:9", "o": "עָרֵ֥י קָדְשְׁ/ךָ֖ הָי֣וּ מִדְבָּ֑ר צִיּוֹן֙ מִדְבָּ֣ר הָיָ֔תָה יְרוּשָׁלִַ֖ם שְׁמָמָֽה", "en": {"kjv": "Be not wroth very sore, O Lord, neither remember iniquity for ever: behold, see, we beseech thee, we are all thy people.", "web": "Don’t be furious, Yahweh, neither remember iniquity forever: see, look, we beg you, we are all your people.", "bsb": "Do not be angry, O LORD, beyond measure; do not remember our iniquity forever. Oh, look upon us, we pray; we are all Your people!", "asv": "Be not wroth very sore, O Jehovah, neither remember iniquity for ever: behold, look, we beseech thee, we are all thy people.", "ylt": "Be not wroth, O Jehovah, very sore, Nor for ever remember iniquity, Lo, look attentively, we beseech Thee, Thy people are we all.", "dra": "Be not very angry, O Lord, and remember no longer our iniquity: behold, see we are all thy people.", "bbe": "Be not very angry, O Lord, and do not keep our sins in mind for ever: give ear to our prayer, for we are all your people.", "geneva": "Be not angry, O Lord, aboue measure, neither remember iniquitie for euer: lo, we beseech thee beholde, we are all thy people.", "wycliffe": "Lord, be thou not wrooth ynow, and haue thou no more mynde on oure wickidnesse. Lo! Lord, biholde thou, alle we ben thi puple.", "rotherham": "Do not be indignant, O Yahweh so very greatly, Neither perpetually, do thou recall iniquity,—Lo! look around, we pray thee…thy people, are, we all.", "darby": "Be not wroth very sore, O Jehovah, neither remember iniquity for ever. Behold, see, we beseech thee, we are all thy people.", "twenty": "", "jps": "Thy holy cities are become a wilderness, Zion is become a wilderness, Jerusalem a desolation.", "acv": "Be not angry very severely, O Jehovah, nor remember iniquity forever. Behold, look, we beseech thee, we are all thy people.", "anderson": "", "haweis": "", "noyes": "Be not wroth, O Jehovah, to the uttermost, Nor remember our iniquity forever! Behold, look upon us, we beseech thee, we are all thy people!", "webster": "Be not very wroth, O LORD, neither remember iniquity for ever: behold, see, we beseech thee, we [are] all thy people.", "vulgate": "ne irascaris Domine satis et ne ultra memineris iniquitatis ecce respice populus tuus omnes nos;", "brenton": "Be not very wroth with us, and remember not our sins for ever; but now look on us, for we are all thy people."}}, {"v": 10, "ref": "64:10", "o": "בֵּ֧ית קָדְשֵׁ֣/נוּ וְ/תִפְאַרְתֵּ֗/נוּ אֲשֶׁ֤ר הִֽלְל֨וּ/ךָ֙ אֲבֹתֵ֔י/נוּ הָיָ֖ה לִ/שְׂרֵ֣פַת אֵ֑שׁ וְ/כָל מַחֲמַדֵּ֖י/נוּ הָיָ֥ה לְ/חָרְבָּֽה", "en": {"kjv": "Thy holy cities are a wilderness, Zion is a wilderness, Jerusalem a desolation.", "web": "Your holy cities are become a wilderness, Zion has become a wilderness, Jerusalem a desolation.", "bsb": "Your holy cities have become a wilderness. Zion has become a wasteland and Jerusalem a desolation.", "asv": "Thy holy cities are become a wilderness, Zion is become a wilderness, Jerusalem a desolation.", "ylt": "Thy holy cities have been a wilderness, Zion a wilderness hath been, Jerusalem a desolation.", "dra": "The city of thy sanctuary is become a desert, Sion is made a desert, Jerusalem is desolate.", "bbe": "Your holy towns have become a waste, Zion has become a waste, Jerusalem is a mass of broken walls.", "geneva": "Thine holy cities lye waste: Zion is a wildernes, and Ierusalem a desart.", "wycliffe": "The citee of thi seyntuarie is forsakun, Sion is maad deseert, Jerusalem is desolat;", "rotherham": "Thy holy cities, have become a wilderness,—Zion, a wilderness, hath become, Jerusalem, a desolation!", "darby": "Thy holy cities are become a wilderness, Zion is a wilderness, Jerusalem a desolation.", "twenty": "", "jps": "Our holy and our beautiful house, where our fathers praised Thee, is burned with fire; and all our pleasant things are laid waste.", "acv": "Thy holy cities have become a wilderness. Zion has become a wilderness, Jerusalem a desolation.", "anderson": "", "haweis": "", "noyes": "Thy holy cities have become a wilderness; Zion is become a wilderness, Jerusalem a desolation.", "webster": "Thy holy cities are a wilderness, Zion is a wilderness, Jerusalem a desolation.", "vulgate": "civitas sancti tui facta est deserta Sion deserta facta est Hierusalem desolata;", "brenton": "The city of thy holiness has become desolate, Sion has become as a wilderness, Jerusalem a curse."}}, {"v": 11, "ref": "64:11", "o": "הַ/עַל אֵ֥לֶּה תִתְאַפַּ֖ק יְהוָ֑ה תֶּחֱשֶׁ֥ה וּ/תְעַנֵּ֖/נוּ עַד מְאֹֽד", "en": {"kjv": "Our holy and our beautiful house, where our fathers praised thee, is burned up with fire: and all our pleasant things are laid waste.", "web": "Our holy and our beautiful house, where our fathers praised you, is burned with fire; and all our pleasant places are laid waste.", "bsb": "Our holy and beautiful temple, where our fathers praised You, has been burned with fire, and all that was dear to us lies in ruins.", "asv": "Our holy and our beautiful house, where our fathers praised thee, is burned with fire; and all our pleasant places are laid waste.", "ylt": "Our holy and our beautiful house, Where praise Thee did our fathers, Hath become burnt with fire, And all our desirable things have become a waste.", "dra": "The house of our holiness, and of our glory, where our fathers praised thee, is burnt with fire, and all our lovely things are turned into ruins.", "bbe": "Our holy and beautiful house, where our fathers gave praise to you, is burned with fire; and all the things of our desire have come to destruction.", "geneva": "The House of our Sanctuarie and of our glorie, where our fathers praysed thee, is burnt vp with fire and all our pleasant things are wasted.", "wycliffe": "the hous of oure halewyng and of oure glorie, where oure fadris herieden thee, is maad in to brennyng of fier; and alle oure desirable thingis ben turned in to fallyngis.", "rotherham": "Our holy and our beautiful house Where our fathers praised thee, Hath become a conflagration,—And, all our delightful places, are in ruins!", "darby": "Our holy and our beautiful house, where our fathers praised thee, is burnt up with fire, and all our precious things are laid waste.", "twenty": "", "jps": "Wilt Thou refrain Thyself for these things, O HaShem? Wilt Thou hold Thy peace, and afflict us very sore?", "acv": "Our holy and our beautiful house, where our fathers praised thee, is burned with fire, and all our pleasant places are laid waste.", "anderson": "", "haweis": "", "noyes": "Our holy and glorious house, Where our fathers praised thee, Is burned with fire, And all our precious things are laid waste.", "webster": "Our holy and our beautiful house, where our fathers praised thee, is burned with fire: and all our pleasant things are laid waste.", "vulgate": "domus sanctificationis nostrae et gloriae nostrae ubi laudaverunt te patres nostri facta est in exustionem ignis et omnia desiderabilia nostra versa sunt in ruinas;", "brenton": "The house, our sanctuary, and the glory which our fathers blessed, has been burnt with fire: and all our glorious things have gone to ruin."}}, {"v": 12, "ref": "64:12", "o": "", "en": {"kjv": "Wilt thou refrain thyself for these things, O Lord? wilt thou hold thy peace, and afflict us very sore?", "web": "Will you refrain yourself for these things, Yahweh? Will you hold your peace, and afflict us very severely?", "bsb": "After all this, O LORD, will You restrain Yourself? Will You keep silent and afflict us beyond measure?", "asv": "Wilt thou refrain thyself for these things, O Jehovah? wilt thou hold thy peace, and afflict us very sore?", "ylt": "For these dost Thou refrain Thyself, Jehovah? Thou art silent, and dost afflict us very sore!'", "dra": "Wilt thou refrain thyself, O Lord, upon these things, wilt thou hold thy peace, and afflict us vehemently?", "bbe": "In view of all this, will you still do nothing, O Lord? will you keep quiet, and go on increasing our punishment?", "geneva": "Wilt thou holde thy selfe still at these things, O Lord? wilt thou holde thy peace and afflict vs aboue measure?", "wycliffe": "Lord, whether on these thingis thou schalt witholde thee? schalt thou be stille, and schalt thou turmente vs greetli?", "rotherham": "In view of these things, wilt thou restrain thyself. O Yahweh? Wilt thou hold thy peace and humble us so very greatly?", "darby": "Wilt thou restrain thyself in presence of these things, Jehovah? Wilt thou hold thy peace, and afflict us very sore?", "twenty": "", "jps": "", "acv": "Will thou restrain thyself for these things, O Jehovah? Will thou hold thy peace, and afflict us very severely?", "anderson": "", "haweis": "", "noyes": "Wilt thou contain thyself at these things, O Jehovah, Wilt thou keep silence, and still grievously afflict us?", "webster": "Wilt thou refrain thyself for these [things], O LORD? wilt thou hold thy peace, and grievously afflict us?", "vulgate": "numquid super his continebis te Domine tacebis et adfliges nos vehementer;", "brenton": "And for all these things thou, O Lord, has withholden, thyself, and been silent, and hast brought us very low."}}]}, {"c": 65, "verses": [{"v": 1, "ref": "65:1", "o": "נִדְרַ֨שְׁתִּי֙ לְ/ל֣וֹא שָׁאָ֔לוּ נִמְצֵ֖אתִי לְ/לֹ֣א בִקְשֻׁ֑/נִי אָמַ֨רְתִּי֙ הִנֵּ֣/נִי הִנֵּ֔/נִי אֶל גּ֖וֹי לֹֽא קֹרָ֥א בִ/שְׁמִֽ/י", "en": {"kjv": "I am sought of them that asked not for me; I am found of them that sought me not: I said, Behold me, behold me, unto a nation that was not called by my name.", "web": "“I am inquired of by those who didn’t ask; I am found by those who didn’t seek me: I said, See me, see me, to a nation that was not called by my name.", "bsb": "“I revealed Myself to those who did not ask for Me; I was found by those who did not seek Me. To a nation that did not call My name, I said, ‘Here I am! Here I am!’", "asv": "I am inquired of by them that asked notfor me; I am found of them that sought me not: I said, Behold me, behold me, unto a nation that was not called by my name.", "ylt": "I have been inquired of by those who asked not, I have been found by those who sought Me not, I have said, `Behold Me, behold Me,' Unto a nation not calling in My name.", "dra": "They have sought me that before asked not for me, they have found me that sought me not. I said: Behold me, behold me, to a nation that did not call upon my name.", "bbe": "I have been ready to give an answer to those who did not make prayer to me; I have been offering myself to those who were not searching for me; I said, Here am I, here am I, to a nation which gave no respect to my name.", "geneva": "I have bene sought of them that asked not: I was found of them that sought me not: I sayd, Beholde me, beholde me, vnto a nation that called not vpon my Name.", "wycliffe": "Thei souyten me, that axiden not bifore; thei that souyten not me, founden me. Y seide, Lo! Y, lo! Y, to hethene men that knewen not me, and that clepiden not mi name to help.", "rotherham": "I have let myself be consulted by them who had not asked, I have suffered myself to be found by them who had not sought me,—I have said, Here I am! Here I am! Unto a nation that had not been called by my name,", "darby": "I am sought out of them that inquired not [for me], I am found of them that sought me not; I have said, Behold me, behold me, unto a nation that was not called by my name.", "twenty": "", "jps": "I gave access to them that asked not for Me, I was at hand to them that sought Me not; I said: 'Behold Me, behold Me', unto a nation that was not called by My name.", "acv": "I was manifested by those who did not ask for me. I am found by those who did not seek me. I said, Behold me, behold me, to a nation that was not called by my name.", "anderson": "", "haweis": "", "noyes": "I have heard those that made no supplication; I have been found by those who sought me not; I said, Here I am, here I am, To a people that called not upon my name.", "webster": "I am sought by [them that] asked not [for me]; I am found by [them that] sought me not: I said, Behold me, behold me, to a nation [that] was not called by my name.", "vulgate": "quaesierunt me qui ante non interrogabant invenerunt qui non quaesierunt me dixi ecce ego ecce ego ad gentem quae non vocabat nomen meum;", "brenton": "I became manifest to them that asked not for me; I was found of them that sought me not: I said, Behold, I am here, to a nation, who called not on my name."}}, {"v": 2, "ref": "65:2", "o": "פֵּרַ֧שְׂתִּי יָדַ֛/י כָּל הַ/יּ֖וֹם אֶל עַ֣ם סוֹרֵ֑ר הַ/הֹלְכִים֙ הַ/דֶּ֣רֶךְ לֹא ט֔וֹב אַחַ֖ר מַחְשְׁבֹתֵי/הֶֽם", "en": {"kjv": "I have spread out my hands all the day unto a rebellious people, which walketh in a way that was not good, after their own thoughts;", "web": "I have spread out my hands all the day to a rebellious people, who walk in a way that is not good, after their own thoughts;", "bsb": "All day long I have held out My hands to an obstinate people who walk in the wrong path, who follow their own imaginations,", "asv": "I have spread out my hands all the day unto a rebellious people, that walk in a way that is not good, after their own thoughts;", "ylt": "I have spread out My hands all the day Unto an apostate people, Who are going in the way not good after their own thoughts.", "dra": "I have spread forth my hands all the day to an unbelieving people, who walk in a way that is not good after their own thoughts.", "bbe": "All day my hands have been stretched out to an uncontrolled people, who go in an evil way, after the purposes of their hearts;", "geneva": "I haue spred out mine handes all the day vnto a rebellious people, which walked in a way that was not good, euen after their owne imaginations:", "wycliffe": "I stretchide forth myn hondis al dai to a puple vnbileueful, that goith in a weie not good, aftir her thouytis.", "rotherham": "I have spread out my hands all the day, Unto a rebellious people,—Who walk In the way that is not good, After their own devices.", "darby": "I have stretched out my hands all the day unto a rebellious people, who walk in a way not good, after their own thoughts;", "twenty": "", "jps": "I have spread out My hands all the day unto a rebellious people, that walk in a way that is not good, after their own thoughts;", "acv": "I have spread out my hands all the day to a disobedient and rebellious people, who walk in a way that is not good, according to their own thoughts,", "anderson": "", "haweis": "", "noyes": "I have spread out my hands all the day To a rebellious people, That walketh in an evil way, According to their own devices;", "webster": "I have spread out my hands all the day to a rebellious people, which walketh in a way [that is] not good, after their own thoughts;", "vulgate": "expandi manus meas tota die ad populum incredulum qui graditur in via non bona post cogitationes suas;", "brenton": "I have stretched forth my hands all day to a disobedient and gainsaying people, to them that walked in a way that was not good, but after their sins."}}, {"v": 3, "ref": "65:3", "o": "הָ/עָ֗ם הַ/מַּכְעִיסִ֥ים אוֹתִ֛/י עַל פָּנַ֖/י תָּמִ֑יד זֹֽבְחִים֙ בַּ/גַּנּ֔וֹת וּֽ/מְקַטְּרִ֖ים עַל הַ/לְּבֵנִֽים", "en": {"kjv": "A people that provoketh me to anger continually to my face; that sacrificeth in gardens, and burneth incense upon altars of brick;", "web": "a people who provoke me to my face continually, sacrificing in gardens, and burning incense on bricks;", "bsb": "to a people who continually provoke Me to My face, sacrificing in the gardens and burning incense on altars of brick,", "asv": "a people that provoke me to my face continually, sacrificing in gardens, and burning incense upon bricks;", "ylt": "The people who are provoking Me to anger, To My face continually, Sacrificing in gardens, and making perfume on the bricks:", "dra": "A people that continually provoke me to anger before my face, that immolate in gardens, and sacrifice upon bricks.", "bbe": "A people who make me angry every day, making offerings in gardens, and burning perfumes on bricks.", "geneva": "A people that prouoked me euer vnto my face: that sacrificeth in gardens, and burneth incense vpon brickes.", "wycliffe": "It is a puple that stirith me to wrathfulnesse, euere bifore my face; whiche offren in gardyns, and maken sacrifice on tiel stoonys;", "rotherham": "The people who are provoking me to anger to my face continually,—Sacrificing in gardens, and Burning incense upon bricks;", "darby": "the people that provoke me to anger continually to my face, sacrificing in gardens and burning incense upon the bricks;", "twenty": "", "jps": "A people that provoke Me to My face continually, that sacrifice in gardens, and burn incense upon bricks;", "acv": "a people who provoke me to my face continually, sacrificing in gardens, and burning incense upon bricks,", "anderson": "", "haweis": "", "noyes": "To a people that provoke me to my face continually; That sacrifice in gardens, And burn incense on tiles;", "webster": "A people that provoketh me to anger continually to my face; that sacrificeth in gardens, and burneth incense upon altars of brick;", "vulgate": "populus qui ad iracundiam provocat me ante faciem meam semper qui immolant in hortis et sacrificant super lateres;", "brenton": "This is the people that provokes me continually in my presence; they offer sacrifices in gardens, and burn incense on bricks to devils, which exist not."}}, {"v": 4, "ref": "65:4", "o": "הַ/יֹּֽשְׁבִים֙ בַּ/קְּבָרִ֔ים וּ/בַ/נְּצוּרִ֖ים יָלִ֑ינוּ הָ/אֹֽכְלִים֙ בְּשַׂ֣ר הַ/חֲזִ֔יר ו/פרק וּ/מְרַ֥ק פִּגֻּלִ֖ים כְּלֵי/הֶֽם", "en": {"kjv": "Which remain among the graves, and lodge in the monuments, which eat swine’s flesh, and broth of abominable things is in their vessels;", "web": "who sit among the graves, and lodge in the secret places; who eat pig’s flesh, and broth of abominable things is in their vessels;", "bsb": "sitting among the graves, spending nights in secret places, eating the meat of pigs and polluted broth from their bowls.", "asv": "that sit among the graves, and lodge in the secret places; that eat swine’s flesh, and broth of abominable things is in their vessels;", "ylt": "Who are dwelling among sepulchres, And lodge in reserved places, Who are eating flesh of the sow, And a piece of abominable things--their vessels.", "dra": "That dwell in sepulchres, and sleep in the temple of idols: that eat swine's flesh, and profane broth is in their vessels.", "bbe": "Who are seated in the resting-places of the dead, and by night are in the secret places; who take pig's flesh for food, and have the liquid of disgusting things in their vessels.", "geneva": "Which remaine among the graues, and lodge in the desarts, which eate swines flesh, and the broth of things polluted are in their vessels.", "wycliffe": "whiche dwellen in sepulcris, and slepen in the templis of idols; whiche eten swynes fleisch, and vnhooli iwisch is in the vessels of hem;", "rotherham": "Who tarry among graves, And in the secret places, do lodge, Who eat the flesh of swine, And the broth of refuse things is in their vessels,—", "darby": "who sit down among the graves, and lodge in the secret places; who eat swine's flesh, and broth of abominable things [is in] their vessels;", "twenty": "", "jps": "That sit among the graves, and lodge in the vaults; that eat swine's flesh, and broth of abominable things is in their vessels;", "acv": "who sit among the graves, and lodge in the secret places, who eat swine's flesh, and broth of abominable things is in their vessels,", "anderson": "", "haweis": "", "noyes": "That sit in sepulchres, And lodge in caverns; That eat swine’s flesh, And have broth of unclean things in their vessels;", "webster": "Which remain among the graves, and lodge in the monuments, which eat swine's flesh, and broth of abominable [things is in] their vessels;", "vulgate": "qui habitant in sepulchris et in delubris idolorum dormiunt qui comedunt carnem suillam et ius profanum in vasis eorum;", "brenton": "They lie down to sleep in the tombs and in the caves for the sake of dreams, even they that eat swine's flesh, and the broth of their sacrifices: all their vessels are defiled:"}}, {"v": 5, "ref": "65:5", "o": "הָ/אֹֽמְרִים֙ קְרַ֣ב אֵלֶ֔י/ךָ אַל תִּגַּשׁ בִּ֖/י כִּ֣י קְדַשְׁתִּ֑י/ךָ אֵ֚לֶּה עָשָׁ֣ן בְּ/אַפִּ֔/י אֵ֥שׁ יֹקֶ֖דֶת כָּל הַ/יּֽוֹם", "en": {"kjv": "Which say, Stand by thyself, come not near to me; for I am holier than thou. These are a smoke in my nose, a fire that burneth all the day.", "web": "who say, Stand by yourself, don’t come near to me, for I am holier than you. These are a smoke in my nose, a fire that burns all the day.", "bsb": "They say, ‘Keep to yourself; do not come near me, for I am holier than you!’ Such people are smoke in My nostrils, a fire that burns all day long.", "asv": "that say, Stand by thyself, come not near to me, for I am holier than thou. These are a smoke in my nose, a fire that burneth all the day.", "ylt": "Who are saying, `Keep to thyself, come not nigh to me, For I have declared thee unholy.' These are a smoke in Mine anger, A fire burning all the day.", "dra": "That say: Depart from me, come not near me, because thou art unclean: these shall be smoke in my anger, a fire burning all the day.", "bbe": "Who say, Keep away, do not come near me, for fear that I make you holy: these are a smoke in my nose, a fire burning all day.", "geneva": "Which say, Stand apart, come not neere to me: for I am holier then thou: these are a smoke in my wrath and a fire that burneth all the day.", "wycliffe": "whiche seien to an hethene man, Go thou awei fro me, neiy thou not to me, for thou art vncleene; these schulen be smoke in my stronge veniaunce, fier brennynge al dai.", "rotherham": "Who say—Draw near by thyself, Do not approach with me, For I am holier than thou! These, are A smoke in my nostrils, A fire, burning all the day.", "darby": "who say, Stand by thyself, come not near to me; for I am holier than thou. These are a smoke in my nose, a fire that burneth all the day.", "twenty": "", "jps": "That say: 'Stand by thyself, come not near to me, for I am holier than thou'; these are a smoke in My nose, a fire that burneth all the day.", "acv": "who say, Stand by thyself, do not come near to me, for I am holier than thou. These are a smoke in my nose, a fire that burns all the day.", "anderson": "", "haweis": "", "noyes": "Who yet say: Stand by thyself! come not near to me, For I am holier than thou! These are a smoke in my nose, A fire that burneth continually.", "webster": "Which say, Stand by thyself, come not near to me; for I am holier than thou. These [are] a smoke in my nose, a fire that burneth all the day.", "vulgate": "qui dicunt recede a me non adpropinques mihi quia inmundus es isti fumus erunt in furore meo ignis ardens tota die;", "brenton": "who say, Depart from me, draw not nigh to me, for I am pure. This is the smoke of my wrath, a fire burns with it continually."}}, {"v": 6, "ref": "65:6", "o": "הִנֵּ֥ה כְתוּבָ֖ה לְ/פָנָ֑/י לֹ֤א אֶחֱשֶׂה֙ כִּ֣י אִם שִׁלַּ֔מְתִּי וְ/שִׁלַּמְתִּ֖י עַל חֵיקָֽ/ם", "en": {"kjv": "Behold, it is written before me: I will not keep silence, but will recompense, even recompense into their bosom,", "web": "“Behold, it is written before me: I will not keep silence, but will recompense, yes, I will recompense into their bosom,", "bsb": "Behold, it is written before Me: I will not keep silent, but I will repay; I will pay it back into their laps,", "asv": "Behold, it is written before me: I will not keep silence, but will recompense, yea, I will recompense into their bosom,", "ylt": "Lo, it is written before Me: `I am not silent, but have recompensed; And I have recompensed into their bosom,", "dra": "Behold it is written before me: I will not be silent, but I will render and repay into their bosom.", "bbe": "See, it is recorded before me, says the Lord: I will not keep back my hand, till I have sent punishment,", "geneva": "Beholde, it is written before me: I wil not keepe silence, but will render it and recompense it into their bosome.", "wycliffe": "Lo! it is writun bifore me; Y schal not be stille, but Y schal yelde, and Y schal quyte in to the bosum of hem youre wickidnessis,", "rotherham": "Lo! it is written before me,—I will not keep silence, But I have recompensed, and will recompense into their bosom:", "darby": "Behold, it is written before me: I will not keep silence, but will recompense, even recompense into their bosom,", "twenty": "", "jps": "Behold, it is written before Me; I will not keep silence, except I have requited, yea, I will requite into their bosom,", "acv": "Behold, it is written before me. I will not keep silence, but will recompense. Yea, I will recompense into their bosom", "anderson": "", "haweis": "", "noyes": "Behold, it stands recorded before me; I will not keep silence, but will requite; I will requite it into their bosoms;", "webster": "Behold, [it is] written before me: I will not keep silence, but will recompense, even recompense into their bosom,", "vulgate": "ecce scriptum est coram me non tacebo sed reddam et retribuam in sinu eorum;", "brenton": "Behold, it is written before me: I will not be silent until I have recompensed into their bosom,"}}, {"v": 7, "ref": "65:7", "o": "עֲ֠וֺנֹתֵי/כֶם וַ/עֲוֺנֹ֨ת אֲבוֹתֵי/כֶ֤ם יַחְדָּו֙ אָמַ֣ר יְהוָ֔ה אֲשֶׁ֤ר קִטְּרוּ֙ עַל הֶ֣/הָרִ֔ים וְ/עַל הַ/גְּבָע֖וֹת חֵרְפ֑וּ/נִי וּ/מַדֹּתִ֧י פְעֻלָּתָ֛/ם רִֽאשֹׁנָ֖ה על אֶל חֵיקָֽ/ם", "en": {"kjv": "Your iniquities, and the iniquities of your fathers together, saith the Lord, which have burned incense upon the mountains, and blasphemed me upon the hills: therefore will I measure their former work into their bosom.", "web": "your own iniquities, and the iniquities of your fathers together”, says Yahweh, “who have burned incense on the mountains, and blasphemed me on the hills; therefore will I first measure their work into their bosom.”", "bsb": "both for your iniquities and for those of your fathers,” says the LORD. “Because they burned incense on the mountains and scorned Me on the hills, I will measure into their laps full payment for their former deeds.”", "asv": "your own iniquities, and the iniquities of your fathers together, saith Jehovah, that have burned incense upon the mountains, and blasphemed me upon the hills: therefore will I first measure their work into their bosom.", "ylt": "Your iniquities, and the iniquities of your fathers together, said Jehovah, Who have made perfume on the mountains, And on the heights have reproached Me, And I have measured their former work into their bosom.'", "dra": "Your iniquities, and the iniquities of your fathers together, saith the Lord, who have sacrificed upon the mountains, and have reproached me upon the hills; and I will measure back their first work in their bosom.", "bbe": "For their sins and the sins of their fathers, who were burning perfumes on the mountains, and saying evil things against me on the hills: so I will take the measure of their sins, and will send the punishment for them into their breast.", "geneva": "Your iniquities and the iniquities of your fathers shalbe together (sayth the Lord) which haue burnt incense vpon the mountaines, and blasphemed me vpon the hilles: therefore wil I measure their olde worke into their bosome.", "wycliffe": "and the wickidnessis of youre fadris togidere, seith the Lord, whiche maden sacrifice on mounteyns, and diden schenschipe to me on litle hillis; and Y schal mete ayen the firste werk of hem in her bosum.", "rotherham": "Your own iniquities, And the, iniquities of your fathers together, Saith Yahweh, Who have burned incense upon the mountains, And upon the hills, have reproached me,—Therefore will I measure their former work into their bosom.", "darby": "your iniquities, and the iniquities of your fathers together, saith Jehovah, who have burned incense upon the mountains, and outraged me upon the hills; and I will measure their former work into their bosom.", "twenty": "", "jps": "Your own iniquities, and the iniquities of your fathers together, saith HaShem, that have offered upon the mountains, and blasphemed Me upon the hills; therefore will I first measure their wage into their bosom.", "acv": "your own iniquities, and the iniquities of your fathers together, says Jehovah, those who have burned incense upon the mountains, and blasphemed me upon the hills. Therefore I will measure their former work into their bosom.", "anderson": "", "haweis": "", "noyes": "Your iniquities, and the iniquities of your fathers together, saith Jehovah, Who burnt incense on the mountains, And dishonored me on the hills, I will pour the full recompense of their former deeds into their bosom.", "webster": "Your iniquities, and the iniquities of your fathers together, saith the LORD, who have burned incense upon the mountains, and blasphemed me upon the hills: therefore will I measure their former work into their bosom.", "vulgate": "iniquitates vestras et iniquitates patrum vestrorum simul dicit Dominus qui sacrificaverunt super montes et super colles exprobraverunt mihi et remetiar opus eorum primum in sinu eorum;", "brenton": "their sins and the sins of their fathers, saith the Lord, who have burnt incense on the mountains, and reproached me on the hills: I will recompense their works into their bosom."}}, {"v": 8, "ref": "65:8", "o": "כֹּ֣ה אָמַ֣ר יְהוָ֗ה כַּ/אֲשֶׁ֨ר יִמָּצֵ֤א הַ/תִּירוֹשׁ֙ בָּֽ/אֶשְׁכּ֔וֹל וְ/אָמַר֙ אַל תַּשְׁחִיתֵ֔/הוּ כִּ֥י בְרָכָ֖ה בּ֑/וֹ כֵּ֤ן אֶֽעֱשֶׂה֙ לְמַ֣עַן עֲבָדַ֔/י לְ/בִלְתִּ֖י הַֽשְׁחִ֥ית הַ/כֹּֽל", "en": {"kjv": "Thus saith the Lord, As the new wine is found in the cluster, and one saith, Destroy it not; for a blessing is in it: so will I do for my servants’ sakes, that I may not destroy them all.", "web": "Thus says Yahweh, “As the new wine is found in the cluster, and one says, ‘Don’t destroy it, for a blessing is in it:’ so will I do for my servants’ sake, that I may not destroy them all.", "bsb": "This is what the LORD says: “As the new wine is found in a cluster of grapes, and men say, ‘Do not destroy it, for it contains a blessing,’ so I will act on behalf of My servants; I will not destroy them all.", "asv": "Thus saith Jehovah, As the new wine is found in the cluster, and one saith, Destroy it not, for a blessing is in it: so will I do for my servants’ sake, that I may not destroy them all.", "ylt": "Thus said Jehovah: As the new wine is found in the cluster, And one hath said, `Destroy it not for a blessing is in it,' So I do for My servants' sake, not to destroy the whole.", "dra": "Thus saith the Lord: As if a grain be found in a cluster, and it be said: Destroy it not, because it is a blessing: so will I do for the sake of my servants, that I may not destroy the whole.", "bbe": "This is the word of the Lord: As the new wine is seen in the grapes, and they say, Do not send destruction on it, for a blessing is in it: so will I do for my servants, in order that I may not put an end to them all.", "geneva": "Thus sayth the Lord, As the wine is found in the cluster, and one sayth, Destroy it not, for a blessing is in it, so will I doe for my seruants sakes, that I may not destroy them whole.", "wycliffe": "The Lord seith thes thingis, As if a grape be foundun in a clustre, and it be seid, Distrie thou not it, for it is blessyng; so Y schal do for my seruantis, that Y leese not al.", "rotherham": "Thus, saith Yahweh—As, new wine, is found, in the cluster, And one saith, Do not destroy it, for a blessing is in it, So, will I do for the sake of my servants, That I may not destroy the whole [nation] ;", "darby": "Thus saith Jehovah: As the new wine is found in the cluster, and it is said, Destroy it not, for a blessing is in it; so will I do for my servants' sakes, that I may not destroy [them] all.", "twenty": "", "jps": "Thus saith HaShem: as, when wine is found in the cluster, one saith: 'Destroy it not, for a blessing is in it'; so will I do for My servants' sakes, that I may not destroy all.", "acv": "Thus says Jehovah, As the new wine is found in the cluster, and a man says, Destroy it not, for a blessing is in it, so I will do for my servants' sake, that I may not destroy them all.", "anderson": "", "haweis": "", "noyes": "Thus saith Jehovah: As when juice is found in a cluster, Men say, \"Destroy it not, for a blessing is in it\"; So will I do, for the sake of my servants, and will not destroy the whole;", "webster": "Thus saith the LORD, As the new wine is found in the cluster, and [one] saith, Destroy it not; for a blessing [is] in it: so will I do for my servants' sake, that I may not destroy them all.", "vulgate": "haec dicit Dominus quomodo si inveniatur granum in botro et dicatur ne dissipes illud quoniam benedictio est sic faciam propter servos meos ut non disperdam totum;", "brenton": "Thus saith the Lord, As a grape-stone shall be found in the cluster, and they shall say, Destroy it not; for a blessing is in it: so will I do for the sake of him that serves me, for his sake I will not destroy them all."}}, {"v": 9, "ref": "65:9", "o": "וְ/הוֹצֵאתִ֤י מִֽ/יַּעֲקֹב֙ זֶ֔רַע וּ/מִ/יהוּדָ֖ה יוֹרֵ֣שׁ הָרָ֑/י וִ/ירֵשׁ֣וּ/הָ בְחִירַ֔/י וַ/עֲבָדַ֖/י יִשְׁכְּנוּ שָֽׁמָּ/ה", "en": {"kjv": "And I will bring forth a seed out of Jacob, and out of Judah an inheritor of my mountains: and mine elect shall inherit it, and my servants shall dwell there.", "web": "I will bring a seed out of Jacob, and out of Judah an inheritor of my mountains; and my chosen shall inherit it, and my servants shall dwell there.", "bsb": "And I will bring forth descendants from Jacob, and heirs from Judah; My elect will possess My mountains, and My servants will dwell there.", "asv": "And I will bring forth a seed out of Jacob, and out of Judah an inheritor of my mountains; and my chosen shall inherit it, and my servants shall dwell there.", "ylt": "And I have brought out from Jacob a seed, And from Judah a possessor of My mount, And possess it do My chosen ones, And My servants do dwell there.", "dra": "And I will bring forth a seed out of Jacob, and out of Juda a possessor of my mountains: and my elect shall inherit it, and my servants shall dwell there.", "bbe": "And I will take a seed out of Jacob, and out of Judah one who will have my mountains for a heritage: and the people I have taken to be mine will have it for themselves, and my servants will have their resting-place there.", "geneva": "But I will bring a seede out of Iaakob, and out of Iudah, that shall inherit my mountaine: and mine elect shall inherit it, and my seruants shall dwell there.", "wycliffe": "And Y schal lede out of Jacob seed, and of Juda a man hauynge in possessioun myn hooli hillis; and my chosun men schulen enherite it, and my seruauntis schulen dwelle there.", "rotherham": "Therefore will I bring forth Out of Jacob, a seed, and Out of Judah, an inheritor of my mountains, That my chosen ones may inherit it, And, my servants, dwell there;", "darby": "And I will bring forth a seed out of Jacob, and out of Judah a possessor of my mountains; and mine elect shall possess it, and my servants shall dwell there.", "twenty": "", "jps": "And I will bring forth a seed out of Jacob, and out of Judah an inheritor of My mountains; and Mine elect shall inherit it, and My servants shall dwell there.", "acv": "And I will bring forth a seed out of Jacob, and out of Judah an inheritor of my mountains. And my chosen shall inherit it, and my servants shall dwell there.", "anderson": "", "haweis": "", "noyes": "I will cause a stem to spring forth from Jacob, And from Judah a possessor of my mountains; My chosen shall possess the land, And my servants shall dwell there.", "webster": "And I will bring forth a seed out of Jacob, and out of Judah an inheritor of my mountains: and my elect shall inherit it, and my servants shall dwell there.", "vulgate": "et educam de Iacob semen et de Iuda possidentem montes meos et hereditabunt eam electi mei et servi mei habitabunt ibi;", "brenton": "And I will lead forth the seed that came of Jacob and of Juda, and they shall inherit my holy mountain: and mine elect and my servants shall inherit it, and shall dwell there."}}, {"v": 10, "ref": "65:10", "o": "וְ/הָיָ֤ה הַ/שָּׁרוֹן֙ לִ/נְוֵה צֹ֔אן וְ/עֵ֥מֶק עָכ֖וֹר לְ/רֵ֣בֶץ בָּקָ֑ר לְ/עַמִּ֖/י אֲשֶׁ֥ר דְּרָשֽׁוּ/נִי", "en": {"kjv": "And Sharon shall be a fold of flocks, and the valley of Achor a place for the herds to lie down in, for my people that have sought me.", "web": "Sharon shall be a fold of flocks, and the valley of Achor a place for herds to lie down in, for my people who have sought me.", "bsb": "Sharon will become a pasture for flocks, and the Valley of Achor a resting place for herds, for My people who seek Me.", "asv": "And Sharon shall be a fold of flocks, and the valley of Achor a place for herds to lie down in, for my people that have sought me.", "ylt": "And Sharon hath been for the habitation of a flock, And the valley of Achor for the lying down of a herd, For My people who have sought Me.", "dra": "And the plains shall be turned to folds of flocks, and the valley of Achor into a place for the herds to lie down in, for my people that have sought me.", "bbe": "And Sharon will be a grass-land for the flocks, and the valley of Achor a resting-place for the herds: for my people whose hearts have been turned back to me.", "geneva": "And Sharon shalbe a sheepefolde, and the valley of Achor shalbe a resting place for the cattell of my people, that haue sought me.", "wycliffe": "And the feeldi places schulen be into floodis of flockis, and the valei of Achar in to a restyng place of droues of neet, to my puple that souyten me.", "rotherham": "Then shall, Sharon, become, a fold for flocks, And the vale of Achor for the lying down of herds,—For my people who have sought me.", "darby": "And the Sharon shall be a fold for flocks, and the valley of Achor a couching-place of the herds, for my people that have sought me.", "twenty": "", "jps": "And Sharon shall be a fold of flocks, and the valley of Achor a place for herds to lie down in, for My people that have sought Me;", "acv": "And Sharon shall be a fold of flocks, and the valley of Achor a place for herds to lie down in, for my people who have sought me.", "anderson": "", "haweis": "", "noyes": "And Sharon shall be a fold for flocks, And the valley of Achor a resting-place for herds, For my people that have sought me.", "webster": "And Sharon shall be a fold of flocks, and the valley of Achor a place for the herds to lie down in, for my people that have sought me.", "vulgate": "et erunt campestria in caulas gregum et vallis Achor in cubile armentorum populo meo qui requisierunt me;", "brenton": "And there shall be in the forest folds of flocks, and the valley of Achor shall be for a resting-place of herds for my people, who have sought me."}}, {"v": 11, "ref": "65:11", "o": "וְ/אַתֶּם֙ עֹזְבֵ֣י יְהוָ֔ה הַ/שְּׁכֵחִ֖ים אֶת הַ֣ר קָדְשִׁ֑/י הַֽ/עֹרְכִ֤ים לַ/גַּד֙ שֻׁלְחָ֔ן וְ/הַֽ/מְמַלְאִ֖ים לַ/מְנִ֥י מִמְסָֽךְ", "en": {"kjv": "But ye are they that forsake the Lord, that forget my holy mountain, that prepare a table for that troop, and that furnish the drink offering unto that number.", "web": "“But you who forsake Yahweh, who forget my holy mountain, who prepare a table for Fortune, and who fill up mixed wine to Destiny;", "bsb": "But you who forsake the LORD, who forget My holy mountain, who set a table for Fortune and fill bowls of mixed wine for Destiny,", "asv": "But ye that forsake Jehovah, that forget my holy mountain, that prepare a table for Fortune, and that fill up mingled wine unto Destiny;", "ylt": "And ye are those forsaking Jehovah, Who are forgetting My holy mountain, Who are setting in array for Gad a table, And who are filling for Meni a mixture.", "dra": "And you, that have forsaken the Lord, that have forgotten my holy mount, that set a table for fortune, and offer libations upon it,", "bbe": "But as for you who have given up the Lord, who have no care for my holy mountain, who get ready a table for Chance, and make offerings of mixed wine to Fate;", "geneva": "But ye are they that haue forsaken the Lord and forgotten mine holy Mountaine, and haue prepared a table for the multitude, and furnish the drinke offerings vnto the number.", "wycliffe": "And Y schal noumbre you in swerd, that forsoken the Lord, that foryaten myn hooli hil, whiche setten a boord to fortune, and maken sacrifice theronne,", "rotherham": "But, ye are they—Who forsake Yahweh Who forget my holy mountain—Who prepare, for Fortune, a table and Who fill for Destiny, mixed wine;", "darby": "But ye who forsake Jehovah, who forget my holy mountain, who prepare a table for Gad, and fill up mixed wine unto Meni:", "twenty": "", "jps": "But ye that forsake HaShem, that forget My holy mountain, that prepare a table for Fortune, and that offer mingled wine in full measure unto Destiny,", "acv": "But ye who forsake Jehovah, who forget my holy mountain, who prepare a table for Fortune, and who fill up mingled wine to Destiny,", "anderson": "", "haweis": "", "noyes": "But ye, who have forsaken Jehovah, And have forgotten my holy mountain, That prepare a table for Fortune, And fill the cup for Destiny,", "webster": "But ye [are] they that forsake the LORD, that forget my holy mountain, that prepare a table for that troop, and that furnish the drink-offering to that number.", "vulgate": "et vos qui dereliquistis Dominum qui obliti estis montem sanctum meum qui ponitis Fortunae mensam et libatis super eam;", "brenton": "But ye are they that have left me, and forget my holy mountain, and prepare a table for the devil, and fill up the drink-offering to Fortune."}}, {"v": 12, "ref": "65:12", "o": "וּ/מָנִ֨יתִי אֶתְ/כֶ֜ם לַ/חֶ֗רֶב וְ/כֻלְּ/כֶם֙ לַ/טֶּ֣בַח תִּכְרָ֔עוּ יַ֤עַן קָרָ֨אתִי֙ וְ/לֹ֣א עֲנִיתֶ֔ם דִּבַּ֖רְתִּי וְ/לֹ֣א שְׁמַעְתֶּ֑ם וַ/תַּעֲשׂ֤וּ הָ/רַע֙ בְּ/עֵינַ֔/י וּ/בַ/אֲשֶׁ֥ר לֹֽא חָפַ֖צְתִּי בְּחַרְתֶּֽם", "en": {"kjv": "Therefore will I number you to the sword, and ye shall all bow down to the slaughter: because when I called, ye did not answer; when I spake, ye did not hear; but did evil before mine eyes, and did choose that wherein I delighted not.", "web": "I will destine you to the sword, and you shall all bow down to the slaughter; because when I called, you didn’t answer; when I spoke, you didn’t listen; but you did that which was evil in my eyes, and chose that in which I didn’t delight.”", "bsb": "I will destine you for the sword, and you will all kneel down to be slaughtered, because I called and you did not answer, I spoke and you did not listen; you did evil in My sight and chose that in which I did not delight.”", "asv": "I will destine you to the sword, and ye shall all bow down to the slaughter; because when I called, ye did not answer; when I spake, ye did not hear; but ye did that which was evil in mine eyes, and chose that wherein I delighted not.", "ylt": "And I have numbered you for the sword, And all of you for slaughter bow down, Because I called, and ye have not answered, I have spoken, and ye have not hearkened, And ye do the evil thing in Mine eyes, And on that which I desired not--fixed.", "dra": "I will number you in the sword, and you shall all fall by slaughter: because I called and you did not answer: I spoke, and you did not hear: and you did evil in my eyes, and you have chosen the things that displease me.", "bbe": "Your fate will be the sword, and you will all go down to death: because when my voice came to you, you made no answer; you did not give ear to my word; but you did what was evil in my eyes, desiring what was not pleasing to me.", "geneva": "Therefore wil I number you to the sword, and all you shall bowe downe to the slaughter, because I called, and ye did not answere: I spake, and ye heard not, but did euil in my sight, and did chuse that thing which I would not.", "wycliffe": "and alle ye schulen falle bi sleyng; for that that Y clepide, and ye answeriden not; Y spak, and ye herden not; and ye diden yuel bifor myn iyen, and ye chesiden tho thingis whiche Y nolde.", "rotherham": "Therefore will I destine you to the sword, And, ye all, to the slaughter, shall bow down. Because I called and ye answered not, I spake, and ye hearkened not,—But did that which was wicked in mine eyes, And of that wherein I delighted not, ye made choice,", "darby": "I will even assign you to the sword, and ye shall all bow down in the slaughter; because I called, and ye did not answer, I spoke, and ye did not hear; but ye did what was evil in mine eyes, and chose that wherein I delight not.", "twenty": "", "jps": "I will destine you to the sword, and ye shall all bow down to the slaughter; because when I called, ye did not answer, when I spoke, ye did not hear; but ye did that which was evil in Mine eyes, and chose that wherein I delighted not.", "acv": "I will destine you to the sword, and ye shall all bow down to the slaughter. Because when I called, ye did not answer, when I spoke, ye did not hear, but ye did that which was evil in my eyes, and chose that in which I did not delight.", "anderson": "", "haweis": "", "noyes": "Yourselves do I destine to the sword, And all of you shall bow down before the slaughter; Because I called, and ye answered not, I spake, and ye would not hear, But did that which is evil in my sight, And chose that in which I had no delight.", "webster": "Therefore will I number you to the sword, and ye shall all bow down to the slaughter: because when I called, ye did not answer; when I spoke, ye did not hear; but did evil before my eyes, and did choose [that] in which I delighted not.", "vulgate": "numerabo vos in gladio et omnes in caede corruetis pro eo quod vocavi et non respondistis locutus sum et non audistis et faciebatis malum in oculis meis et quae nolui elegistis;", "brenton": "I will deliver you up to the sword, ye shall all fall by slaughter: for I called you, and ye hearkened not; I spoke, and ye refused to hear; and ye did evil in my sight, and chose the things wherein I delighted not."}}, {"v": 13, "ref": "65:13", "o": "לָ/כֵ֞ן כֹּה אָמַ֣ר אֲדֹנָ֣/י יְהוִ֗ה הִנֵּ֨ה עֲבָדַ֤/י יֹאכֵ֨לוּ֙ וְ/אַתֶּ֣ם תִּרְעָ֔בוּ הִנֵּ֧ה עֲבָדַ֛/י יִשְׁתּ֖וּ וְ/אַתֶּ֣ם תִּצְמָ֑אוּ הִנֵּ֧ה עֲבָדַ֛/י יִשְׂמָ֖חוּ וְ/אַתֶּ֥ם תֵּבֹֽשׁוּ", "en": {"kjv": "Therefore thus saith the Lord God, Behold, my servants shall eat, but ye shall be hungry: behold, my servants shall drink, but ye shall be thirsty: behold, my servants shall rejoice, but ye shall be ashamed:", "web": "Therefore thus says the Lord Yahweh, “Behold, my servants shall eat, but you shall be hungry; behold, my servants shall drink, but you shall be thirsty; behold, my servants shall rejoice, but you shall be disappointed;", "bsb": "Therefore this is what the Lord GOD says: “My servants will eat, but you will go hungry; My servants will drink, but you will go thirsty; My servants will rejoice, but you will be put to shame.", "asv": "Therefore thus saith the Lord Jehovah, Behold, my servants shall eat, but ye shall be hungry; behold, my servants shall drink, but ye shall be thirsty; behold, my servants shall rejoice, but ye shall be put to shame;", "ylt": "Therefore, thus said the Lord Jehovah: Lo, My servants do eat, and ye do hunger, Lo, My servants do drink, and ye do thirst, Lo, My servants rejoice, and ye are ashamed,", "dra": "Therefore thus saith the Lord God: Behold my servants shall eat, and you shall be hungry: behold my servants shall drink, and you shall be thirsty.", "bbe": "For this cause says the Lord God, My servants will have food, but you will be in need of food: my servants will have drink, but you will be dry: my servants will have joy, but you will be shamed:", "geneva": "Therefore thus saith the Lord God, Beholde, my seruants shall eate, and ye shalbe hungrie: beholde, my seruants shall drinke, and ye shall be thirstie: beholde, my seruants shall reioyce, and ye shalbe ashamed.", "wycliffe": "For these thingis, the Lord God seith these thingis, Lo! my seruauntis schulen ete, and ye schulen haue hungur; lo! my seruauntis schulen drynke, and ye schulen be thirsti;", "rotherham": "Therefore, Thus, saith My Lord, Yahweh,—Lo! my servants, shall eat but, ye, shall be famished, Lo! my servants, shall drink but, ye shall be thirsty,—Lo! my servants, shall rejoice but ye, shall turn pale;", "darby": "Therefore thus saith the Lord Jehovah: Behold, my servants shall eat, and ye shall be hungry; behold, my servants shall drink, and ye shall be thirsty; behold, my servants shall rejoice, and ye shall be ashamed;", "twenty": "", "jps": "Therefore thus saith the L-rd GOD: Behold, My servants shall eat, but ye shall be hungry; behold, My servants shall drink, but ye shall be thirsty; behold, My servants shall rejoice, but ye shall be ashamed;", "acv": "Therefore thus says the lord Jehovah, Behold, my servants shall eat, but ye shall be hungry. Behold, my servants shall drink, but ye shall be thirsty. Behold, my servants shall rejoice, but ye shall be put to shame.", "anderson": "", "haweis": "", "noyes": "Therefore thus saith the Lord Jehovah: Behold, my servants shall eat, and ye shall be hungry; Behold, my servants shall drink, and ye shall be thirsty; Behold, my servants shall rejoice, and ye shall be confounded;", "webster": "Therefore thus saith the Lord GOD, Behold, my servants shall eat, but ye shall be hungry: behold, my servants shall drink, but ye shall be thirsty: behold, my servants shall rejoice, but ye shall be ashamed:", "vulgate": "propter hoc haec dicit Dominus Deus ecce servi mei comedent et vos esurietis ecce servi mei bibent et vos sitietis;", "brenton": "Therefore thus saith the Lord, Behold, my servants shall eat, but ye shall hunger: behold, my servants shall drink, but ye shall thirst: behold, my servants shall rejoice, but ye shall be ashamed:"}}, {"v": 14, "ref": "65:14", "o": "הִנֵּ֧ה עֲבָדַ֛/י יָרֹ֖נּוּ מִ/טּ֣וּב לֵ֑ב וְ/אַתֶּ֤ם תִּצְעֲקוּ֙ מִ/כְּאֵ֣ב לֵ֔ב וּ/מִ/שֵּׁ֥בֶר ר֖וּחַ תְּיֵלִֽילוּ", "en": {"kjv": "Behold, my servants shall sing for joy of heart, but ye shall cry for sorrow of heart, and shall howl for vexation of spirit.", "web": "behold, my servants shall sing for joy of heart, but you shall cry for sorrow of heart, and shall wail for anguish of spirit.", "bsb": "My servants will shout for joy with a glad heart, but you will cry out with a heavy heart and wail with a broken spirit.", "asv": "behold, my servants shall sing for joy of heart, but ye shall cry for sorrow of heart, and shall wail for vexation of spirit.", "ylt": "Lo, My servants sing from joy of heart, And ye cry from pain of heart, And from breaking of spirit ye do howl.", "dra": "Behold my servants shall rejoice, and you shall be confounded: behold my servants shall praise for joyfulness of heart, and you shall cry for sorrow of heart, and shall howl for grief of spirit.", "bbe": "My servants will make songs in the joy of their hearts, but you will be crying for sorrow, and making sounds of grief from a broken spirit.", "geneva": "Beholde, my seruants shall sing for ioye of heart, and ye shall crye for sorow of heart, and shall howle for vexation of minde.", "wycliffe": "lo! my seruauntis schulen be glad, and ye schulen be aschamed; lo! my seruauntis schulen herie, for the ful ioie of herte, and ye schulen crie, for the sorewe of herte, and ye schulen yelle, for desolacioun of spirit.", "rotherham": "Lo! my servants, shall shout in triumph for mirth of heart But, ye, shall make outcry, for pain of heart, And for a breaking of spirit, shall ye howl.", "darby": "behold, my servants shall sing aloud for gladness of heart, and ye shall cry out for sorrow of heart, and shall howl for vexation of spirit.", "twenty": "", "jps": "Behold, My servants shall sing for joy of heart, but ye shall cry for sorrow of heart, and shall wail for vexation of spirit.", "acv": "Behold, my servants shall sing for joy of heart, but ye shall cry for sorrow of heart, and shall wail for vexation of spirit.", "anderson": "", "haweis": "", "noyes": "Behold, my servants shall sing for gladness of heart, But ye shall shriek for sorrow of heart, And howl for anguish of spirit.", "webster": "Behold, my servants shall sing for joy of heart, but ye shall cry for sorrow of heart, and shall howl for vexation of spirit.", "vulgate": "ecce servi mei laetabuntur et vos confundemini ecce servi mei laudabunt prae exultatione cordis et vos clamabitis prae dolore cordis et prae contritione spiritus ululabitis;", "brenton": "behold, my servants shall exult with joy, but ye shall cry for the sorrow of your heart, and shall howl for the vexation of your spirit."}}, {"v": 15, "ref": "65:15", "o": "וְ/הִנַּחְתֶּ֨ם שִׁמְ/כֶ֤ם לִ/שְׁבוּעָה֙ לִ/בְחִירַ֔/י וֶ/הֱמִיתְ/ךָ֖ אֲדֹנָ֣/י יְהוִ֑ה וְ/לַ/עֲבָדָ֥י/ו יִקְרָ֖א שֵׁ֥ם אַחֵֽר", "en": {"kjv": "And ye shall leave your name for a curse unto my chosen: for the Lord God shall slay thee, and call his servants by another name:", "web": "You shall leave your name for a curse to my chosen; and the Lord Yahweh will kill you; and he will call his servants by another name:", "bsb": "You will leave behind your name as a curse for My chosen ones, and the Lord GOD will slay you; but to His servants He will give another name.", "asv": "And ye shall leave your name for a curse unto my chosen; and the Lord Jehovah will slay thee; and he will call his servants by another name:", "ylt": "And ye have left your name For an oath for My chosen ones, And the Lord Jehovah hath put thee to death, And to His servants He giveth another name.", "dra": "And you shall leave your name for an execration to my elect: and the Lord God shall slay thee, and call his servants by another name.", "bbe": "And your name will become a curse to my people, and the Lord God will put you to death, and give his servants another name:", "geneva": "And ye shall leaue your name as a curse vnto my chosen: for the Lord God shall slay you and call his seruants by another name.", "wycliffe": "And ye schulen leeue youre name in to an ooth to my chosun men; and the Lord God schal sle thee, and he schal clepe hise seruauntis bi another name.", "rotherham": "So shall ye leave your name for an oath, to my chosen ones,—So then My Lord Yahweh, will slay thee,—And his servants, will he, call by another name:", "darby": "And ye shall leave your name for a curse unto mine elect; for the Lord Jehovah will slay thee, and will call his servants by another name:", "twenty": "", "jps": "And ye shall leave your name for a curse unto Mine elect: 'So may the L-rd GOD slay thee'; but He shall call His servants by another name;", "acv": "And ye shall leave your name for a curse to my chosen, and the lord Jehovah will kill thee. And he will call his servants by another name,", "anderson": "", "haweis": "", "noyes": "And ye shall leave your name for a curse to my chosen, And the Lord Jehovah shall slay you; But his servants will he call by another name.", "webster": "And ye shall leave your name for a curse to my chosen: for the Lord GOD will slay thee, and call his servants by another name:", "vulgate": "et dimittetis nomen vestrum in iuramentum electis meis et interficiet te Dominus Deus et servos suos vocabit nomine alio;", "brenton": "For ye shall leave your name for a loathing to my chosen, and the Lord shall destroy you: but my servants shall be called by a new name,"}}, {"v": 16, "ref": "65:16", "o": "אֲשֶׁ֨ר הַ/מִּתְבָּרֵ֜ךְ בָּ/אָ֗רֶץ יִתְבָּרֵךְ֙ בֵּ/אלֹהֵ֣י אָמֵ֔ן וְ/הַ/נִּשְׁבָּ֣ע בָּ/אָ֔רֶץ יִשָּׁבַ֖ע בֵּ/אלֹהֵ֣י אָמֵ֑ן כִּ֣י נִשְׁכְּח֗וּ הַ/צָּרוֹת֙ הָ/רִ֣אשֹׁנ֔וֹת וְ/כִ֥י נִסְתְּר֖וּ מֵ/עֵינָֽ/י", "en": {"kjv": "That he who blesseth himself in the earth shall bless himself in the God of truth; and he that sweareth in the earth shall swear by the God of truth; because the former troubles are forgotten, and because they are hid from mine eyes.", "web": "so that he who blesses himself in the earth shall bless himself in the God of truth; and he who swears in the earth shall swear by the God of truth; because the former troubles are forgotten, and because they are hidden from my eyes.", "bsb": "Whoever invokes a blessing in the land will do so by the God of truth, and whoever takes an oath in the land will swear by the God of truth. For the former troubles will be forgotten and hidden from My sight.", "asv": "so that he who blesseth himself in the earth shall bless himself in the God of truth; and he that sweareth in the earth shall swear by the God of truth; because the former troubles are forgotten, and because they are hid from mine eyes.", "ylt": "So that he who is blessing himself in the earth, Doth bless himself In the God of faithfulness, And he who is swearing in the earth, Doth swear by the God of faithfulness, Because the former distresses have been forgotten, And because they have been hid from Mine eyes.", "dra": "In which he that is blessed upon the earth, shall be blessed in God, amen: and he that sweareth in the earth, shall swear by God, amen: because the former distresses are forgotten, and because they are hid from my eyes.", "bbe": "So that he who is requesting a blessing will make use of the name of the true God, and he who takes an oath will do so by the true God; because the past troubles are gone out of mind, and because they are covered from my eyes.", "geneva": "He that shall blesse in the earth, shall blesse himselfe in the true God, and he that sweareth in the earth, shall sweare by the true God: for the former troubles are forgotten, and shall surely hide themselues from mine eyes.", "wycliffe": "In which he that is blessid on erthe, schal be blessid in God amen; and he that swerith in erthe, shal swere in God feithfuli; for the formere angwischis ben youun to foryetyng, and for tho ben hid fro youre iyen.", "rotherham": "So that he who blesseth himself in the earth, Will bless himself in the God of faithfulness, And he who sweareth in the earth Will swear by the God of faithfulness—Because the former troubles have been forgotten, and Because they are hid from mine eyes.", "darby": "so that he who blesseth himself in the land shall bless himself by theGod of truth; and he that sweareth in the land shall swear by theGod of truth: because the former troubles shall be forgotten, and because they shall be hidden from mine eyes.", "twenty": "", "jps": "So that he who blesseth himself in the earth shall bless himself by the G-d of truth; and he that sweareth in the earth shall swear by the G-d of truth; because the former troubles are forgotten, and because they are hid from Mine eyes.", "acv": "so that he who blesses himself in the earth shall bless himself in the God of truth, and he who swears in the earth shall swear by the God of truth. Because the former troubles are forgotten, and because they are hid from my eyes.", "anderson": "", "haweis": "", "noyes": "Whoso blesseth himself in the land Shall bless by the true God; And he that sweareth in the land shall swear by the true God; For the former troubles are forgotten, And they are hid from mine eyes.", "webster": "That he who blesseth himself in the earth shall bless himself in the God of truth; and he that sweareth in the earth shall swear by the God of truth; because the former troubles are forgotten, and because they are hid from my eyes.", "vulgate": "in quo qui benedictus est super terram benedicetur in Deo amen et qui iurat in terra iurabit in Deo amen quia oblivioni traditae sunt angustiae priores et quia absconditae sunt ab oculis nostris;", "brenton": "which shall be blessed on the earth; for they shall bless the true God: and they that swear upon the earth shall swear by the true God; for they shall forget the former affliction, it shall not come into their mind."}}, {"v": 17, "ref": "65:17", "o": "כִּֽי הִנְ/נִ֥י בוֹרֵ֛א שָׁמַ֥יִם חֲדָשִׁ֖ים וָ/אָ֣רֶץ חֲדָשָׁ֑ה וְ/לֹ֤א תִזָּכַ֨רְנָה֙ הָ/רִ֣אשֹׁנ֔וֹת וְ/לֹ֥א תַעֲלֶ֖ינָה עַל לֵֽב", "en": {"kjv": "For, behold, I create new heavens and a new earth: and the former shall not be remembered, nor come into mind.", "web": "“For, behold, I create new heavens and a new earth; and the former things shall not be remembered, nor come into mind.", "bsb": "For behold, I will create new heavens and a new earth. The former things will not be remembered, nor will they come to mind.", "asv": "For, behold, I create new heavens and a new earth; and the former things shall not be remembered, nor come into mind.", "ylt": "For, lo, I am creating new heavens, and a new earth, And the former things are not remembered, Nor do they ascend on the heart.", "dra": "For behold I create new heavens, and a new earth: and the former things shall not be in remembrance, and they shall not come upon the heart.", "bbe": "For see, I am making a new heaven and a new earth: and the past things will be gone completely out of mind.", "geneva": "For lo, I will create newe heauens and a new earth: and the former shall not be remembred nor come into minde.", "wycliffe": "For lo! Y make newe heuenes and a newe erthe, and the formere thingis schulen not be in mynde, and schulen not stie on the herte.", "rotherham": "For, behold me! Creating new heavens, and a new earth,—And the former shall not be mentioned, neither shall they come up on the heart,", "darby": "For behold, I create new heavens and a new earth; and the former shall not be remembered, nor come into mind.", "twenty": "", "jps": "For, behold, I create new heavens and a new earth; and the former things shall not be remembered, nor come into mind.", "acv": "For, behold, I create new heavens and a new earth, and the former things shall not be remembered, nor come into mind.", "anderson": "", "haweis": "", "noyes": "For behold! I create new heavens, and a new earth; The former ones shall not be remembered, Nor shall they be brought to mind any more.", "webster": "For behold, I create new heavens and a new earth: and the former shall not be remembered, nor come into mind.", "vulgate": "ecce enim ego creo caelos novos et terram novam et non erunt in memoria priora et non ascendent super cor;", "brenton": "For there shall be a new heaven and a new earth: and they shall not at all remember the former, neither shall they at all come into their mind."}}, {"v": 18, "ref": "65:18", "o": "כִּֽי אִם שִׂ֤ישׂוּ וְ/גִ֨ילוּ֙ עֲדֵי עַ֔ד אֲשֶׁ֖ר אֲנִ֣י בוֹרֵ֑א כִּי֩ הִנְ/נִ֨י בוֹרֵ֧א אֶת יְרוּשָׁלִַ֛ם גִּילָ֖ה וְ/עַמָּ֥/הּ מָשֽׂוֹשׂ", "en": {"kjv": "But be ye glad and rejoice for ever in that which I create: for, behold, I create Jerusalem a rejoicing, and her people a joy.", "web": "But be you glad and rejoice forever in that which I create; for, behold, I create Jerusalem a rejoicing, and her people a joy.", "bsb": "But be glad and rejoice forever in what I create; for I will create Jerusalem to be a joy and its people to be a delight.", "asv": "But be ye glad and rejoice for ever in that which I create; for, behold, I create Jerusalem a rejoicing, and her people a joy.", "ylt": "But joy ye, and rejoice for ever, that I am Creator, For, lo, I am creating Jerusalem a rejoicing, And her people a joy.", "dra": "But you shall be glad and rejoice for ever in these things, which I create: for behold I create Jerusalem a rejoicing, and the people thereof joy.", "bbe": "But men will be glad and have joy for ever in what I am making; for I am making Jerusalem a delight, and her people a joy.", "geneva": "But be you glad and reioyce for euer in the things that I shall create: for beholde, I will create Ierusalem, as a reioycing and her people as a ioye,", "wycliffe": "But ye schulen haue ioie, and make ful out ioiyng til in to with outen ende, in these thingis whiche Y make; for lo! Y make Jerusalem ful out ioiynge, and the puple therof ioie.", "rotherham": "But joy ye and exult, perpetually, in what I am about to create,—For, behold me! Creating Jerusalem an exultation and Her People a joy;", "darby": "But be glad and rejoice for ever in that which I create. For behold, I create Jerusalem a rejoicing, and her people a joy.", "twenty": "", "jps": "But be ye glad and rejoice for ever in that which I create; for, behold, I create Jerusalem a rejoicing, and her people a joy.", "acv": "But be ye glad and rejoice forever in that which I create. For, behold, I create Jerusalem a rejoicing, and her people a joy.", "anderson": "", "haweis": "", "noyes": "But ye shall be glad and exult forever In that which I create; For behold! I create Jerusalem a rejoicing, And her people a joy.", "webster": "But be ye glad and rejoice for ever [in that] which I create: for behold, I create Jerusalem a rejoicing, and her people a joy.", "vulgate": "sed gaudebitis et exultabitis usque in sempiternum in his quae ego creo quia ecce ego creo Hierusalem exultationem et populum eius gaudium;", "brenton": "But they shall find in her joy and exultation; for, behold, I make Jerusalem a rejoicing, and my people a joy."}}, {"v": 19, "ref": "65:19", "o": "וְ/גַלְתִּ֥י בִ/ירוּשָׁלִַ֖ם וְ/שַׂשְׂתִּ֣י בְ/עַמִּ֑/י וְ/לֹֽא יִשָּׁמַ֥ע בָּ/הּ֙ ע֔וֹד ק֥וֹל בְּכִ֖י וְ/ק֥וֹל זְעָקָֽה", "en": {"kjv": "And I will rejoice in Jerusalem, and joy in my people: and the voice of weeping shall be no more heard in her, nor the voice of crying.", "web": "I will rejoice in Jerusalem, and joy in my people; and there shall be heard in her no more the voice of weeping and the voice of crying.", "bsb": "I will rejoice in Jerusalem and take delight in My people. The sounds of weeping and crying will no longer be heard in her.", "asv": "And I will rejoice in Jerusalem, and joy in my people; and there shall be heard in her no more the voice of weeping and the voice of crying.", "ylt": "And I have rejoiced in Jerusalem, And have joyed in My people, And not heard in her any more Is the voice of weeping, and the voice of crying.", "dra": "And I will rejoice in Jerusalem, and joy in my people, and the voice of weeping shall no more be heard in her, nor the voice of crying.", "bbe": "And I will be glad over Jerusalem, and have joy in my people: and the voice of weeping will no longer be sounding in her, or the voice of grief.", "geneva": "And I wil reioyce in Ierusalem, and ioye in my people, and the voyce of weeping shall be no more heard in her, nor the voyce of crying.", "wycliffe": "And Y schal make ful out ioiyng in Jerusalem, and Y schal haue ioie in my puple; and the vois of weping and the vois of cry schal no more be herd ther ynne.", "rotherham": "Therefore will I Exult in Jerusalem, and Joy in my People,—And there shall be heard in her, no more The sound of weeping, or the sound of a cry:", "darby": "And I will rejoice over Jerusalem, and will joy in my people; and the voice of weeping shall be no more heard in her, nor the voice of crying.", "twenty": "", "jps": "And I will rejoice in Jerusalem, and joy in My people; and the voice of weeping shall be no more heard in her, nor the voice of crying.", "acv": "And I will rejoice in Jerusalem, and joy in my people. And there shall no more be heard in her the voice of weeping and the voice of crying.", "anderson": "", "haweis": "", "noyes": "And I will exult in Jerusalem, And rejoice in my people; No more shall be heard therein The voice of weeping and the cry of distress.", "webster": "And I will rejoice in Jerusalem, and joy in my people: and the voice of weeping shall be no more heard in her, nor the voice of crying.", "vulgate": "et exultabo in Hierusalem et gaudebo in populo meo et non audietur in eo ultra vox fletus et vox clamoris;", "brenton": "And I will rejoice in Jerusalem, and will be glad in my people: and there shall no more be heard in her the voice of weeping, or the voice of crying."}}, {"v": 20, "ref": "65:20", "o": "לֹא יִֽהְיֶ֨ה מִ/שָּׁ֜ם ע֗וֹד ע֤וּל יָמִים֙ וְ/זָקֵ֔ן אֲשֶׁ֥ר לֹֽא יְמַלֵּ֖א אֶת יָמָ֑י/ו כִּ֣י הַ/נַּ֗עַר בֶּן מֵאָ֤ה שָׁנָה֙ יָמ֔וּת וְ/הַ֣/חוֹטֶ֔א בֶּן מֵאָ֥ה שָׁנָ֖ה יְקֻלָּֽל", "en": {"kjv": "There shall be no more thence an infant of days, nor an old man that hath not filled his days: for the child shall die an hundred years old; but the sinner being an hundred years old shall be accursed.", "web": "“There shall be no more there an infant of days, nor an old man who has not filled his days; for the child shall die one hundred years old, and the sinner being one hundred years old shall be accursed.", "bsb": "No longer will a nursing infant live but a few days, or an old man fail to live out his years. For the youth will die at a hundred years, and he who fails to reach a hundred will be considered accursed.", "asv": "There shall be no more thence an infant of days, nor an old man that hath not filled his days; for the child shall die a hundred years old, and the sinner being a hundred years old shall be accursed.", "ylt": "There is not thence any more a suckling of days, And an aged man who doth not complete his days, For the youth a hundred years old dieth, And the sinner, a hundred years old, is lightly esteemed.", "dra": "There shall no more be an infant of days there, nor an old man that shall not fill up his days: for the child shall die a hundred years old, and the sinner being a hundred years old shall be accursed.", "bbe": "No longer will there be there a child whose days are cut short, or an old man whose days have not come to their full measure: for the young man at his death will be a hundred years old, and he whose life is shorter than a hundred years will seem as one cursed.", "geneva": "There shall be no more there a childe of yeeres, nor an olde man that hath not filled his dayes: for he that shall be an hundreth yeeres old, shall dye as a yong man: but the sinner being an hundreth yeeres olde shall be accursed.", "wycliffe": "A yong child of daies schal no more be there, and an eld man that fillith not hise daies; for whi a child of an hundrid yeer schal die, and a synnere of an hundrid yeer schal be cursid.", "rotherham": "There shall be thenceforward, no more, A suckling of a few days, or an elder Who filleth not up his days,—But, a youth a hundred years old, may die, Yea a sinner a hundred years old, shall be accursed,", "darby": "There shall be no more thenceforth an infant of days, nor an old man that hath not completed his days; for the youth shall die a hundred years old, and the sinner being a hundred years old shall be accursed.", "twenty": "", "jps": "There shall be no more thence an infant of days, nor an old man, that hath not filled his days; for the youngest shall die a hundred years old, and the sinner being a hundred years old shall be accursed.", "acv": "There shall be no more from there an infant of days, nor an old man who has not filled his days. For the child shall die a hundred years old, and the sinner being a hundred years old shall be accursed.", "anderson": "", "haweis": "", "noyes": "There shall not be there an infant child, nor an old man, That hath not filled the measure of his years; For he that dieth a hundred years old shall die a youth, And the sinner dying a hundred years old shall be held accursed.", "webster": "There shall be no more thence an infant of days, nor an old man that hath not filled his days: for the child shall die a hundred years old: but the sinner [being] a hundred years old shall be accursed.", "vulgate": "non erit ibi amplius infans dierum et senex qui non impleat dies suos quoniam puer centum annorum morietur et peccator centum annorum maledictus erit;", "brenton": "Neither shall there be there any more a child that dies untimely, or an old man who shall not complete his time: for the youth shall be a hundred years old, and the sinner who dies at a hundred years shall also be accursed:"}}, {"v": 21, "ref": "65:21", "o": "וּ/בָנ֥וּ בָתִּ֖ים וְ/יָשָׁ֑בוּ וְ/נָטְע֣וּ כְרָמִ֔ים וְ/אָכְל֖וּ פִּרְיָֽ/ם", "en": {"kjv": "And they shall build houses, and inhabit them; and they shall plant vineyards, and eat the fruit of them.", "web": "They shall build houses, and inhabit them; and they shall plant vineyards, and eat their fruit.", "bsb": "They will build houses and dwell in them; they will plant vineyards and eat their fruit.", "asv": "And they shall build houses, and inhabit them; and they shall plant vineyards, and eat the fruit of them.", "ylt": "And they have built houses, and inhabited, And planted vineyards, and eaten their fruit.", "dra": "And they shall build houses, and inhabit them; and they shall plant vineyards, and eat the fruits of them.", "bbe": "And they will be building houses and living in them; planting vine-gardens and getting the fruit of them.", "geneva": "And they shall build houses and inhabite them, and they shall plant vineyards, and eate the fruite of them.", "wycliffe": "And thei schulen bilde housis, and schulen enhabite hem, and thei schulen plaunte vynes, and schulen ete the fruytis of tho.", "rotherham": "Then shall they build houses and dwell in them,—And plant vineyards and eat the fruit of them;", "darby": "And they shall build houses, and inhabit them; and they shall plant vineyards, and eat the fruit thereof:", "twenty": "", "jps": "And they shall build houses, and inhabit them; and they shall plant vineyards, and eat the fruit of them.", "acv": "And they shall build houses, and inhabit them. And they shall plant vineyards, and eat the fruit of them.", "anderson": "", "haweis": "", "noyes": "They shall build houses, and inhabit them; They shall plant vineyards, and eat the fruit of them;", "webster": "And they shall build houses, and inhabit [them]; and they shall plant vineyards, and eat the fruit of them.", "vulgate": "et aedificabunt domos et habitabunt et plantabunt vineas et comedent fructum earum;", "brenton": "and they shall build houses, and themselves shall dwell in them; and they shall plant vineyards, and themselves shall eat the fruit thereof."}}, {"v": 22, "ref": "65:22", "o": "לֹ֤א יִבְנוּ֙ וְ/אַחֵ֣ר יֵשֵׁ֔ב לֹ֥א יִטְּע֖וּ וְ/אַחֵ֣ר יֹאכֵ֑ל כִּֽי כִ/ימֵ֤י הָ/עֵץ֙ יְמֵ֣י עַמִּ֔/י וּ/מַעֲשֵׂ֥ה יְדֵי/הֶ֖ם יְבַלּ֥וּ בְחִירָֽ/י", "en": {"kjv": "They shall not build, and another inhabit; they shall not plant, and another eat: for as the days of a tree are the days of my people, and mine elect shall long enjoy the work of their hands.", "web": "They shall not build, and another inhabit; they shall not plant, and another eat: for as the days of a tree shall be the days of my people, and my chosen shall long enjoy the work of their hands.", "bsb": "No longer will they build houses for others to inhabit, nor plant for others to eat. For as is the lifetime of a tree, so will be the days of My people, and My chosen ones will fully enjoy the work of their hands.", "asv": "They shall not build, and another inhabit; they shall not plant, and another eat: for as the days of a tree shall be the days of my people, and my chosen shall long enjoy the work of their hands.", "ylt": "They do not build, and another inhabit, They do not plant, and another eat, For as the days of a tree are the days of My people, And the work of their hands wear out do My chosen ones.", "dra": "They shall not build, and another inhabit; they shall not plant, and another eat: for as the days of a tree, so shall be the days of my people, and the works of their hands shall be of long continuance.", "bbe": "They will no longer be building for the use of others, or planting for others to have the fruit: for the days of my people will be like the days of a tree, and my loved ones will have joy in full measure in the work of their hands.", "geneva": "They shall not build, and another inhabite: they shall not plant, and another eate: for as the dayes of the tree are the dayes of my people, and mine elect shall inioye in olde age the worke of their handes.", "wycliffe": "Thei schulen not bilde housis, and an othir schal enhabite hem, thei schulen not plaunte, and an othir schal ete; for whi the daies of my puple schulen be after the daies of the tree, and the werkis of", "rotherham": "They shall not build, and another, dwell, They shall not plant, and, another, eat,—For as the days of a tree, shall be the days of my people, And, the work of their own hands, shall my chosen ones, use to the full:", "darby": "they shall not build, and another inhabit; they shall not plant, and another eat: for as the days of a tree shall be the days of my people, and mine elect shall long enjoy the work of their hands.", "twenty": "", "jps": "They shall not build, and another inhabit, they shall not plant, and another eat; for as the days of a tree shall be the days of My people, and Mine elect shall long enjoy the work of their hands.", "acv": "They shall not build, and another inhabit. They shall not plant, and another eat. For as the days of a tree shall be the days of my people, and my chosen shall long enjoy the work of their hands.", "anderson": "", "haweis": "", "noyes": "They shall not build, and another inhabit; They shall not plant, and another eat; For as the days of a tree shall be the days of my people, Yea, long shall my chosen enjoy the work of their hands.", "webster": "They shall not build, and another inhabit; they shall not plant, and another eat: for as the days of a tree [are] the days of my people, and my elect shall long enjoy the work of their hands.", "vulgate": "non aedificabunt et alius habitabit non plantabunt et alius comedet secundum dies enim ligni erunt dies populi mei et opera manuum eorum inveterabunt;", "brenton": "They shall by no means build, and others inhabit; and they shall by no means plant, and others eat: for as the days of the tree of life shall be the days of my people, they shall long enjoy the fruits of their labours."}}, {"v": 23, "ref": "65:23", "o": "לֹ֤א יִֽיגְעוּ֙ לָ/רִ֔יק וְ/לֹ֥א יֵלְד֖וּ לַ/בֶּהָלָ֑ה כִּ֣י זֶ֜רַע בְּרוּכֵ֤י יְהוָה֙ הֵ֔מָּה וְ/צֶאֱצָאֵי/הֶ֖ם אִתָּֽ/ם", "en": {"kjv": "They shall not labour in vain, nor bring forth for trouble; for they are the seed of the blessed of the Lord, and their offspring with them.", "web": "They shall not labor in vain, nor give birth for calamity; for they are the seed of the blessed of Yahweh, and their offspring with them.", "bsb": "They will not labor in vain or bear children doomed to disaster; for they will be a people blessed by the LORD— they and their descendants with them.", "asv": "They shall not labor in vain, nor bring forth for calamity; for they are the seed of the blessed of Jehovah, and their offspring with them.", "ylt": "They labour not for a vain thing, Nor do they bring forth for trouble, For the seed of the blessed of Jehovah are they, And their offspring with them.", "dra": "My elect shall not labour in vain, nor bring forth in trouble; for they are the seed of the blessed of the Lord, and their posterity with them.", "bbe": "Their work will not be for nothing, and they will not give birth to children for destruction; for they are a seed to whom the Lord has given his blessing, and their offspring will be with them.", "geneva": "They shall not labour in vaine, nor bring forth in feare: for they are the seede of the blessed of the Lord, and their buds with them.", "wycliffe": "her hondis schulen be elde to my chosun men. Thei schulen not trauele in veyn, nether thei schulen gendre in disturblyng; for it is the seed of hem that ben blessid of the Lord, and the cosyns of hem ben with hem.", "rotherham": "They shall not labour in vain, Nor have children for terror,—For the seed of the blessed ones of Yahweh, shall they be, And their offspring, with them.", "darby": "They shall not labour in vain, nor bring forth for terror; for they are the seed of the blessed of Jehovah, and their offspring with them.", "twenty": "", "jps": "They shall not labour in vain, nor bring forth for terror; for they are the seed blessed of HaShem, and their offspring with them.", "acv": "They shall not labor in vain, nor bring forth for calamity. For they are the seed of the blessed of Jehovah, and their offspring with them.", "anderson": "", "haweis": "", "noyes": "They shall not labor in vain, Nor bring forth children for early death; For they are a race blessed by Jehovah, And their offspring shall remain to them.", "webster": "They shall not labor in vain, nor bring forth for trouble; for they [are] the seed of the blessed of the LORD, and their offspring with them.", "vulgate": "electis meis non laborabunt frustra neque generabunt in conturbatione quia semen benedictorum Domini est et nepotes eorum cum eis;", "brenton": "My chosen shall not toil in vain, neither shall they beget children to be cursed; for they are a seed blessed of God, and their offspring with them."}}, {"v": 24, "ref": "65:24", "o": "וְ/הָיָ֥ה טֶֽרֶם יִקְרָ֖אוּ וַ/אֲנִ֣י אֶעֱנֶ֑ה ע֛וֹד הֵ֥ם מְדַבְּרִ֖ים וַ/אֲנִ֥י אֶשְׁמָֽע", "en": {"kjv": "And it shall come to pass, that before they call, I will answer; and while they are yet speaking, I will hear.", "web": "It shall happen that, before they call, I will answer; and while they are yet speaking, I will hear.", "bsb": "Even before they call, I will answer, and while they are still speaking, I will hear.", "asv": "And it shall come to pass that, before they call, I will answer; and while they are yet speaking, I will hear.", "ylt": "And it hath come to pass, They do not yet call, and I answer, They are yet speaking, and I hear.", "dra": "And it shall come to pass, that before they call, I will hear; as they are yet speaking, I will hear.", "bbe": "And before they make their request I will give an answer, and while they are still making prayer to me, I will give ear.", "geneva": "Yea, before they call, I will answere, and whiles they speake, I will heare.", "wycliffe": "And it schal be, bifor that thei crien, Y schal here; yit while thei speken, Y schal here.", "rotherham": "And it shall come to pass—That before they call, I, will answer, And while yet they are speaking, I, will hear.", "darby": "And it shall come to pass, that before they call, I will answer; while they are yet speaking, I will hear.", "twenty": "", "jps": "And it shall come to pass that, before they call, I will answer, and while they are yet speaking, I will hear.", "acv": "And it shall come to pass that, before they call, I will answer, and while they are yet speaking, I will hear.", "anderson": "", "haweis": "", "noyes": "Before they call, I will answer; And while they are yet speaking, I will hear.", "webster": "And it shall come to pass, that before they call, I will answer; and while they are yet speaking, I will hear.", "vulgate": "eritque antequam clament ego exaudiam adhuc illis loquentibus ego audiam;", "brenton": "And it shall come to pass, that before they call, I will hearken to them; while they are yet speaking, I will say, What is it?"}}, {"v": 25, "ref": "65:25", "o": "זְאֵ֨ב וְ/טָלֶ֜ה יִרְע֣וּ כְ/אֶחָ֗ד וְ/אַרְיֵה֙ כַּ/בָּקָ֣ר יֹֽאכַל תֶּ֔בֶן וְ/נָחָ֖שׁ עָפָ֣ר לַחְמ֑/וֹ לֹֽא יָרֵ֧עוּ וְ/לֹֽא יַשְׁחִ֛יתוּ בְּ/כָל הַ֥ר קָדְשִׁ֖/י אָמַ֥ר יְהוָֽה", "en": {"kjv": "The wolf and the lamb shall feed together, and the lion shall eat straw like the bullock: and dust shall be the serpent’s meat. They shall not hurt nor destroy in all my holy mountain, saith the Lord.", "web": "The wolf and the lamb shall feed together, and the lion shall eat straw like the ox; and dust shall be the serpent’s food. They shall not hurt nor destroy in all my holy mountain,” says Yahweh.", "bsb": "The wolf and the lamb will feed together, and the lion will eat straw like the ox, but the food of the serpent will be dust. They will neither harm nor destroy on all My holy mountain,” says the LORD.", "asv": "The wolf and the lamb shall feed together, and the lion shall eat straw like the ox; and dust shall be the serpent’s food. They shall not hurt nor destroy in all my holy mountain, saith Jehovah.", "ylt": "Wolf and lamb do feed as one, And a lion as an ox eateth straw, As to the serpent--dust is its food, They do no evil, nor destroy, In all My holy mountain, said Jehovah!", "dra": "The wolf and the lamb shall feed together; the lion and the ox shall eat straw; and dust shall be the serpent's food: they shall not hurt nor kill in all my holy mountain, saith the Lord.", "bbe": "The wolf and the lamb will take their food together, and the lion will make a meal of grass like the ox: but dust will be the snake's food. There will be no cause of pain or destruction in all my holy mountain, says the Lord.", "geneva": "The wolfe and the lambe shall feede together, and the lyon shall eate strawe like the bullocke: and to the serpent dust shall be his meate. They shall no more hurt nor destroy in all mine holy Mountaine, saith the Lord.", "wycliffe": "A wolf and a lomb schulen be fed togidere, and a lioun and an oxe schulen ete stree, and to a serpent dust schal be his breed; thei schulen not anoie, nether schulen sle, in al myn hooli hil, seith the Lord.", "rotherham": "The wolf and the lamb, shall feed, in unity, And, the lion, as an ox, shall eat straw; But as for the serpent, dust, shall be his food: They shall not harm—Nor shall they destroy, In all my holy mountain, saith Yahweh.", "darby": "The wolf and the lamb shall feed together, and the lion shall eat straw like the ox; and dust shall be the serpent's meat. They shall not hurt nor destroy in all my holy mountain, saith Jehovah.", "twenty": "", "jps": "The wolf and the lamb shall feed together, and the lion shall eat straw like the ox; and dust shall be the serpent's food. They shall not hurt nor destroy in all My holy mountain, saith HaShem.", "acv": "The wolf and the lamb shall feed together, and the lion shall eat straw like the ox, and dust shall be the serpent's food. They shall not hurt nor destroy in all my holy mountain, says Jehovah.", "anderson": "", "haweis": "", "noyes": "The wolf and the lamb shall feed together, And the lion shall eat straw like the ox, And dust shall be the food of the serpent. They shall not hurt, nor destroy, in all my holy mountain, Saith Jehovah.", "webster": "The wolf and the lamb shall feed together, and the lion shall eat straw like the bullock: and dust [shall be] the serpents' food. They shall not hurt nor destroy in all my holy mountain, saith the LORD.", "vulgate": "lupus et agnus pascentur simul et leo et bos comedent paleas et serpenti pulvis panis eius non nocebunt neque occident in omni monte sancto meo dicit Dominus;", "brenton": "Then wolves and lambs shall feed together, and the lion shall eat chaff like the ox, and the serpent earth as bread. They shall not injure nor destroy in my holy mountain, saith the Lord."}}]}, {"c": 66, "verses": [{"v": 1, "ref": "66:1", "o": "כֹּ֚ה אָמַ֣ר יְהוָ֔ה הַ/שָּׁמַ֣יִם כִּסְאִ֔/י וְ/הָ/אָ֖רֶץ הֲדֹ֣ם רַגְלָ֑/י אֵי זֶ֥ה בַ֨יִת֙ אֲשֶׁ֣ר תִּבְנוּ לִ֔/י וְ/אֵי זֶ֥ה מָק֖וֹם מְנוּחָתִֽ/י", "en": {"kjv": "Thus saith the Lord, The heaven is my throne, and the earth is my footstool: where is the house that ye build unto me? and where is the place of my rest?", "web": "Thus says Yahweh, “Heaven is my throne, and the earth is my footstool: what kind of house will you build to me? and what place shall be my rest?", "bsb": "This is what the LORD says: “Heaven is My throne, and earth is My footstool. What kind of house will you build for Me? Or where will My place of repose be?", "asv": "Thus saith Jehovah, Heaven is my throne, and the earth is my footstool: what manner of house will ye build unto me? and what place shall be my rest?", "ylt": "Thus said Jehovah: The heavens are My throne, And the earth My footstool, Where is this--the house that ye build for Me? And where is this--the place--My rest?", "dra": "Thus saith the Lord: Heaven is my throne, and the earth my footstool: what is this house that you will build to me? and what is this place of my rest?", "bbe": "The Lord says, Heaven is the seat of my power, and earth is the resting-place for my feet: what sort of house will you make for me, and what place will be my resting-place?", "geneva": "Thus saith the Lord, The heauen is my throne, and the earth is my footestoole: where is that house that ye will builde vnto me? and where is that place of my rest?", "wycliffe": "The Lord seith these thingis, Heuene is my seete, and the erthe is the stool of my feet. Which is this hous, which ye schulen bilde to me, and which is this place of my reste?", "rotherham": "Thus, saith Yahweh, The, heavens, are my throne, and The earth, is my footstool: Where then is the house which ye can build me? Or where is my place of rest?", "darby": "Thus saith Jehovah: The heavens are my throne, and the earth is my footstool: what is the house that ye will build unto me? and what is the place of my rest?", "twenty": "", "jps": "Thus saith HaShem: the heaven is My throne, and the earth is My footstool; where is the house that ye may build unto Me? And where is the place that may be My resting-place?", "acv": "Thus says Jehovah, Heaven is my throne, and the earth is my footstool. What manner of house will ye build to me, and what place shall be my rest?", "anderson": "", "haweis": "", "noyes": "Thus saith Jehovah: Heaven is my throne, And the earth my footstool; Where is the house that ye can build me, And where is the place of my rest?", "webster": "Thus saith the LORD, The heaven [is] my throne, and the earth [is] my footstool: where [is] the house that ye build to me? and where [is] the place of my rest?", "vulgate": "haec dicit Dominus caelum sedis mea et terra scabillum pedum meorum quae ista domus quam aedificabitis mihi et quis iste locus quietis meae;", "brenton": "Thus saith the Lord, Heaven is my throne, and the earth is my footstool: what kind of a house will ye build me? and of what kind is to be the place of my rest?"}}, {"v": 2, "ref": "66:2", "o": "וְ/אֶת כָּל אֵ֨לֶּה֙ יָדִ֣/י עָשָׂ֔תָה וַ/יִּהְי֥וּ כָל אֵ֖לֶּה נְאֻם יְהוָ֑ה וְ/אֶל זֶ֣ה אַבִּ֔יט אֶל עָנִי֙ וּ/נְכֵה ר֔וּחַ וְ/חָרֵ֖ד עַל דְּבָרִֽ/י", "en": {"kjv": "For all those things hath mine hand made, and all those things have been, saith the Lord: but to this man will I look, even to him that is poor and of a contrite spirit, and trembleth at my word.", "web": "For all these things has my hand made, and so all these things came to be,” says Yahweh: “but to this man will I look, even to him who is poor and of a contrite spirit, and who trembles at my word.", "bsb": "Has not My hand made all these things? And so they came into being,” declares the LORD. “This is the one I will esteem: he who is humble and contrite in spirit, who trembles at My word.", "asv": "For all these things hath my hand made, and so all these things came to be, saith Jehovah: but to this man will I look, even to him that is poor and of a contrite spirit, and that trembleth at my word.", "ylt": "And all these My hand hath made, And all these things are, An affirmation of Jehovah! And unto this one I look attentively, Unto the humble and bruised in spirit, And who is trembling at My word.", "dra": "My hand made all these things, and all these things were made, saith the Lord. But to whom shall I have respect, but to him that is poor and little, and of a contrite spirit, and that trembleth at my words?", "bbe": "For all these things my hand has made, and they are mine, says the Lord; but to this man only will I give attention, to him who is poor and broken in spirit, fearing my word.", "geneva": "For all these things hath mine hand made, and all these things haue bene, sayth the Lord: and to him will I looke, euen to him, that is poore, and of a contrite spirite and trembleth at my wordes.", "wycliffe": "Myn hond made alle these thingis, and alle these thingis ben maad, seith the Lord; but to whom schal Y biholde, no but to a pore man and contrit in spirit, and greetli dredynge my wordis?", "rotherham": "For, all these things, hath mine own hand made, And all these things came into being,—Declareth Yahweh. But for this one, will I look around, For him who is humbled and smitten in spirit, And so careth anxiously for my word.", "darby": "Even all these things hath my hand made, and all these things have been, saith Jehovah. But to this man will I look: to the afflicted and contrite in spirit, and who trembleth at my word.", "twenty": "", "jps": "For all these things hath My hand made, and so all these things came to be, saith HaShem; but on this man will I look, even on him that is poor and of a contrite spirit, and trembleth at My word.", "acv": "For all these things my hand has made, and all these things came to be, says Jehovah. But to this man I will look, even to him who is poor and of a contrite spirit, and who trembles at my word.", "anderson": "", "haweis": "", "noyes": "For all these things hath my hand made; By it do all these things exist, saith Jehovah. But to this man will I look, Even to him who is humble and of a contrite spirit, And who trembleth at my word.", "webster": "For all these [things] hath my hand made, and all these [things] have been, saith the LORD: but to this man [will] I look, [even] to [him that is] poor and of a contrite spirit, and trembleth at my word.", "vulgate": "omnia haec manus mea fecit et facta sunt universa ista dicit Dominus ad quem autem respiciam nisi ad pauperculum et contritum spiritu et trementem sermones meos;", "brenton": "For all these things are mine, saith the Lord: and to whom will I have respect, but to the humble and meek, and the man that trembles at my words?"}}, {"v": 3, "ref": "66:3", "o": "שׁוֹחֵ֨ט הַ/שּׁ֜וֹר מַכֵּה אִ֗ישׁ זוֹבֵ֤חַ הַ/שֶּׂה֙ עֹ֣רֵֽף כֶּ֔לֶב מַעֲלֵ֤ה מִנְחָה֙ דַּם חֲזִ֔יר מַזְכִּ֥יר לְבֹנָ֖ה מְבָ֣רֵֽךְ אָ֑וֶן גַּם הֵ֗מָּה בָּֽחֲרוּ֙ בְּ/דַרְכֵי/הֶ֔ם וּ/בְ/שִׁקּוּצֵי/הֶ֖ם נַפְשָׁ֥/ם חָפֵֽצָה", "en": {"kjv": "He that killeth an ox is as if he slew a man; he that sacrificeth a lamb, as if he cut off a dog’s neck; he that offereth an oblation, as if he offered swine’s blood; he that burneth incense, as if he blessed an idol. Yea, they have chosen their own ways, and their soul delighteth in their abominations.", "web": "He who kills an ox is as he who kills a man; he who sacrifices a lamb, as he who breaks a dog’s neck; he who offers an offering, as he who offers pig’s blood; he who burns frankincense, as he who blesses an idol. Yes, they have chosen their own ways, and their soul delights in their abominations:", "bsb": "Whoever slaughters an ox is like one who slays a man; whoever sacrifices a lamb is like one who breaks a dog’s neck; whoever presents a grain offering is like one who offers pig’s blood; whoever offers frankincense is like one who blesses an idol. Indeed, they have chosen their own ways and delighted in their abominations.", "asv": "He that killeth an ox is as he that slayeth a man; he that sacrificeth a lamb, as he that breaketh a dog’s neck; he that offereth an oblation, as he that offereth swine’s blood; he that burneth frankincense, as he that blesseth an idol. Yea, they have chosen their own ways, and their soul delighteth in their abominations:", "ylt": "Whoso slaughtereth the ox smiteth a man, Whoso sacrificeth the lamb beheadeth a dog, Whoso is bringing up a present--The blood of a sow, Whoso is making mention of frankincense, Is blessing iniquity. Yea, they have fixed on their own ways, And in their abominations their soul hath delighted.", "dra": "He that sacrificeth an ox, is as if he slew a man: he that killeth a sheep in sacrifice, as if he should brain a dog: he that offereth an oblation, as if he should offer swine's blood; he that remembereth incense, as if he should bless an idol. All these things have they chosen in their ways, and their soul is delighted in their abominations.", "bbe": "He who puts an ox to death puts a man to death; he who makes an offering of a lamb puts a dog to death; he who makes a meal offering makes an offering of pig's blood; he who makes an offering of perfumes for a sign gives worship to an image: as they have gone after their desires, and their soul takes pleasure in their disgusting things;", "geneva": "He that killeth a bullocke, is as if he slewe a man: he that sacrificeth a sheepe, as if he cut off a dogges necke: he that offereth an oblation, as if he offered swines blood: he that remembreth incense, as if he blessed an idole: yea, they haue chosen their owne wayes, and their soule deliteth in their abominations.", "wycliffe": "He that offrith an oxe, is as he that sleeth a man; he that sleeth a scheep, is as he that brayneth a dogge; he that offrith an offryng, is as he that offrith swynes blood; he that thenketh on encense, is as he that blessith an idol; thei chesiden alle thes thingis in her weies, and her soule delitide in her abhomynaciouns.", "rotherham": "He that slaughtereth an ox, [is as one] who smiteth a man, He that sacrificeth a lamb, [is as one] who beheadeth a dog, he that causeth a meal-offering to ascend, offereth it with the blood of swine, He that maketh a memorial of frankincense, [is as one] who blesseth iniquity: They indeed, have chosen their own ways, And in their own abominations, their soul hath found delight;", "darby": "He that slaughtereth an ox, smiteth a man; he that sacrificeth a lamb, breaketh a dog's neck; he that offereth an oblation, [it is as] swine's blood; he that presenteth a memorial of incense, [is as] he that blesseth an idol. As they have chosen their own ways, and their soul delighteth in their abominations,", "twenty": "", "jps": "He that killeth an ox is as if he slew a man; he that sacrificeth a lamb, as if he broke a dog's neck; he that offereth a meal-offering, as if he offered swine's blood; he that maketh a memorial-offering of frankincense, as if he blessed an idol; according as they have chosen their own ways, and their soul delighteth in their abominations;", "acv": "He who slaughters an ox is as he who kills a man. He who sacrifices a lamb, as he who breaks a dog's neck. He who offers an oblation, as swine's blood. He who burns frankincense, as he who blesses an idol. Yea, they have chosen their own ways, and their soul delights in their abominations.", "anderson": "", "haweis": "", "noyes": "He that slayeth an ox killeth a man; He that sacrificeth a lamb beheadeth a dog; He that maketh an oblation offereth swine’s blood; He that burneth incense blesseth an idol. Yea, they have chosen their own ways, And in their abominations their souls delight.", "webster": "He that killeth an ox [is as if] he slew a man; he that sacrificeth a lamb, [as if] he cut off a dog's neck; he that offereth an oblation, [as if he offered] swine's blood; he that burneth incense, [as if] he blessed an idol. Yes, they have chosen their own ways, and their soul delighteth in their abominations.", "vulgate": "qui immolat bovem quasi qui interficiat virum qui mactat pecus quasi qui excerebret canem qui offert oblationem quasi qui sanguinem suillum offerat qui recordatur turis quasi qui benedicat idolo haec omnia elegerunt in viis suis et in abominationibus suis anima eorum delectata est;", "brenton": "But the transgressor that sacrifices a calf to me, is as he that kills a dog; and he that offers fine flour, as one that offers swine's blood; he that gives frankincense for a memorial, is as a blasphemer. Yet they have chosen their own ways, and their soul has delighted in their abominations."}}, {"v": 4, "ref": "66:4", "o": "גַּם אֲנִ֞י אֶבְחַ֣ר בְּ/תַעֲלֻלֵי/הֶ֗ם וּ/מְגֽוּרֹתָ/ם֙ אָבִ֣יא לָ/הֶ֔ם יַ֤עַן קָרָ֨אתִי֙ וְ/אֵ֣ין עוֹנֶ֔ה דִּבַּ֖רְתִּי וְ/לֹ֣א שָׁמֵ֑עוּ וַ/יַּעֲשׂ֤וּ הָ/רַע֙ בְּ/עֵינַ֔/י וּ/בַ/אֲשֶׁ֥ר לֹֽא חָפַ֖צְתִּי בָּחָֽרוּ", "en": {"kjv": "I also will choose their delusions, and will bring their fears upon them; because when I called, none did answer; when I spake, they did not hear: but they did evil before mine eyes, and chose that in which I delighted not.", "web": "I also will choose their delusions, and will bring their fears on them; because when I called, no one answered; when I spoke, they didn’t listen; but they did that which was evil in my eyes, and chose that in which I didn’t delight.”", "bsb": "So I will choose their punishment and I will bring terror upon them, because I called and no one answered, I spoke and no one listened. But they did evil in My sight and chose that in which I did not delight.”", "asv": "I also will choose their delusions, and will bring their fears upon them; because when I called, none did answer; when I spake, they did not hear: but they did that which was evil in mine eyes, and chose that wherein I delighted not.", "ylt": "I also--I fix on their vexations, And their fears I bring in to them, Because I have called, and there is none answering, I spake, and they have not hearkened, And they do the evil things in Mine eyes, And on that which I desired not--fixed.", "dra": "Wherefore I also will choose their mockeries, and will bring upon them the things they feared: because I called, and there was none that would answer; I have spoken, and they heard not; and they have done evil in my eyes, and have chosen the things that displease me.", "bbe": "So I will go after trouble for them, and will send on them what they are fearing: because no one made answer to my voice, or gave ear to my word; but they did what was evil in my eyes, going after that in which I took no pleasure.", "geneva": "Therefore will I chuse out their delusions, and I will bring their feare vpon them, because I called, and none woulde answere: I spake and they woulde not heare: but they did euill in my sight, and chose the things which I would not.", "wycliffe": "Wherfor and Y schal chese the scornyngis of hem, and Y schal brynge to hem tho thingis whiche thei dredden; for Y clepide, and noon was that answeride; Y spak, and thei herden not; and thei diden yuel bifor myn iyen, and chesiden tho thingis whiche Y nolde.", "rotherham": "I, also, will choose the things that vex them. And the things they dread, will I bring upon them, Because—I called and there was none to answer, I spake, and they hearkened not,—But did that which was wicked in mine eyes, And of that wherein I delighted not, made choice.", "darby": "I also will choose their calamities, and will bring their fears upon them; because I called, and none answered, I spoke, and they did not hear, but did that which was evil in mine eyes, and chose that wherein I delight not.", "twenty": "", "jps": "Even so I will choose their mockings, and will bring their fears upon them; because when I called, none did answer; when I spoke, they did not hear, but they did that which was evil in Mine eyes, and chose that in which I delighted not.", "acv": "I also will choose their delusions, and will bring their fears upon them. Because when I called, none answered. When I spoke, they did not hear. But they did that which was evil in my eyes, and chose that in which I did not delight.", "anderson": "", "haweis": "", "noyes": "I also will choose their calamities; What they dread I will bring upon them; Because I called, and no one answered, I spake, and they did not hear; But they did what is evil in my sight, And chose that in which I have no delight.", "webster": "I also will choose their delusions, and will bring their fears upon them; because when I called, none did answer; when I spoke, they did not hear: but they did evil before my eyes, and chose [that] in which I delighted not.", "vulgate": "unde et ego eligam inlusiones eorum et quae timebant adducam eis quia vocavi et non erat qui responderet locutus sum et non audierunt feceruntque malum in oculis meis et quae nolui elegerunt;", "brenton": "I also will choose their mockeries, and will recompense their sins upon them; because I called them, and they did not hearken to me; I spoke, and they heard not: and they did evil before me, and chose the things wherein I delighted not."}}, {"v": 5, "ref": "66:5", "o": "שִׁמְעוּ֙ דְּבַר יְהוָ֔ה הַ/חֲרֵדִ֖ים אֶל דְּבָר֑/וֹ אָמְרוּ֩ אֲחֵי/כֶ֨ם שֹׂנְאֵי/כֶ֜ם מְנַדֵּי/כֶ֗ם לְמַ֤עַן שְׁמִ/י֙ יִכְבַּ֣ד יְהוָ֔ה וְ/נִרְאֶ֥ה בְ/שִׂמְחַתְ/כֶ֖ם וְ/הֵ֥ם יֵבֹֽשׁוּ", "en": {"kjv": "Hear the word of the Lord, ye that tremble at his word; Your brethren that hated you, that cast you out for my name’s sake, said, Let the Lord be glorified: but he shall appear to your joy, and they shall be ashamed.", "web": "Hear Yahweh’s word, you who tremble at his word: “Your brothers who hate you, who cast you out for my name’s sake, have said, ‘Let Yahweh be glorified, that we may see your joy;’ but it is those who shall be disappointed.", "bsb": "You who tremble at His word, hear the word of the LORD: “Your brothers who hate you and exclude you because of My name have said, ‘Let the LORD be glorified that we may see your joy!’ But they will be put to shame.”", "asv": "Hear the word of Jehovah, ye that tremble at his word: Your brethren that hate you, that cast you out for my name’s sake, have said, Let Jehovah be glorified, that we may see your joy; but it is they that shall be put to shame.", "ylt": "Hear a word of Jehovah, Ye who are trembling unto His word, Said have your brethren who are hating you, Who are driving you out, for My name's sake: `Honoured is Jehovah, and we look on your joy,' But they are ashamed.", "dra": "Hear the word of the Lord, you that tremble at his word: Your brethren that hate you, and cast you out for my name's sake, have said: Let the Lord be glorified, and we shall see in your joy: but they shall be confounded.", "bbe": "Give ear to the word of the Lord, you who are in fear at his word: your countrymen, hating you, and driving you out because of my name, have said, Let the Lord's glory be made clear, so that we may see your joy; but they will be put to shame.", "geneva": "Heare the worde of the Lord, all ye that tremble at his worde, Your brethren that hated you, and cast you out for my Names sake, said, Let the Lord be glorified: but he shall appeare to your ioy, and they shall be ashamed.", "wycliffe": "Here ye the word of the Lord, whiche quaken at his word; youre britheren hatynge you, and castynge a wey for my name, seiden, The Lord be glorified, and we schulen se in youre gladnesse; forsothe thei schulen be schent.", "rotherham": "Hear the word of Yahweh, ye who care anxiously for his word: Said your brethren Who hated you. Who thrust you out for my Name’s sake, Yahweh be glorified! Therefore shall he appear to your rejoicing, But, they, shall turn pale.", "darby": "Hear the word of Jehovah, ye that tremble at his word: Your brethren that hated you, that cast you out for my name's sake, said, Let Jehovah be glorified, and let us see your joy! but they shall be ashamed.", "twenty": "", "jps": "Hear the word of HaShem, ye that tremble at His word: your brethren that hate you, that cast you out for My name's sake, have said: 'Let HaShem be glorified, that we may gaze upon your joy', but they shall be ashamed.", "acv": "Hear the word of Jehovah, ye who tremble at his word: Your brothers who hate you, who cast you out for my name's sake, have said, Let Jehovah be glorified, that we may see your joy. But it is those who shall be put to shame.", "anderson": "", "haweis": "", "noyes": "Hear the word of Jehovah, Ye that tremble at his word! \"Your brethren that hate you, And thrust you out for my name’s sake, have said, \"May Jehovah be glorified, that we may see your joy!\" But they shall be confounded.", "webster": "Hear the word of the LORD, ye that tremble at his word; Your brethren that hated you, that cast you out for my name's sake, said, Let the LORD be glorified: but he shall appear to your joy, and they shall be ashamed.", "vulgate": "audite verbum Domini qui tremetis ad verbum eius dixerunt fratres vestri odientes vos et abicientes propter nomen meum glorificetur Dominus et videbimus in laetitia vestra ipsi autem confundentur;", "brenton": "Hear the words of the Lord, ye that tremble at his word; speak ye, our brethren, to them that hate you and abominate you, that the name of the Lord may be glorified, and may appear their joy; but they shall be ashamed."}}, {"v": 6, "ref": "66:6", "o": "ק֤וֹל שָׁאוֹן֙ מֵ/עִ֔יר ק֖וֹל מֵֽ/הֵיכָ֑ל ק֣וֹל יְהוָ֔ה מְשַׁלֵּ֥ם גְּמ֖וּל לְ/אֹיְבָֽי/ו", "en": {"kjv": "A voice of noise from the city, a voice from the temple, a voice of the Lord that rendereth recompence to his enemies.", "web": "A voice of tumult from the city, a voice from the temple, a voice of Yahweh that renders recompense to his enemies.", "bsb": "Hear the uproar from the city; listen to the voice from the temple! It is the voice of the LORD, repaying His enemies what they deserve!", "asv": "A voice of tumult from the city, a voice from the temple, a voice of Jehovah that rendereth recompense to his enemies.", "ylt": "A voice of noise is from the city, a voice from the temple, The voice of Jehovah, giving recompence to His enemies.", "dra": "A voice of the people from the city, a voice from the temple, the voice of the Lord that rendereth recompense to his enemies.", "bbe": "There is a noise of war from the town, a sound from the Temple, the voice of the Lord giving punishment to his haters.", "geneva": "A voyce soundeth from the citie, euen a voyce from the Temple, the voyce of the Lord, that recompenseth his enemies fully.", "wycliffe": "The vois of the puple fro the citee, the vois fro the temple, the vois of the Lord yeldynge a reward to hise enemyes.", "rotherham": "The sound of a tumult—out of the city, A sound, out of the temple,—The sound of Yahweh rendering recompense to his foes.", "darby": "A voice of tumult from the city, a voice from the temple, a voice of Jehovah that rendereth recompence to his enemies!", "twenty": "", "jps": "Hark! an uproar from the city, Hark! it cometh from the temple, Hark! HaShem rendereth recompense to His enemies.", "acv": "A voice of tumult from the city, a voice from the temple, a voice of Jehovah who renders recompense to his enemies.", "anderson": "", "haweis": "", "noyes": "A voice of tumult from the city! A voice from the temple! The voice of Jehovah, rendering recompense to his enemies!", "webster": "A voice of noise from the city, a voice from the temple, a voice of the LORD that rendereth recompense to his enemies.", "vulgate": "vox populi de civitate vox de templo vox Domini reddentis retributionem inimicis suis;", "brenton": "A voice of a cry from the city, a voice from the temple, a voice of the Lord rendering recompence to his adversaries."}}, {"v": 7, "ref": "66:7", "o": "בְּ/טֶ֥רֶם תָּחִ֖יל יָלָ֑דָה בְּ/טֶ֨רֶם יָב֥וֹא חֵ֛בֶל לָ֖/הּ וְ/הִמְלִ֥יטָה זָכָֽר", "en": {"kjv": "Before she travailed, she brought forth; before her pain came, she was delivered of a man child.", "web": "“Before she travailed, she gave birth; before her pain came, she delivered a son.", "bsb": "“Before she was in labor, she gave birth; before she was in pain, she delivered a boy.", "asv": "Before she travailed, she brought forth; before her pain came, she was delivered of a man-child.", "ylt": "Before she is pained she hath brought forth, Before a pang cometh to her, She hath delivered a male.", "dra": "Before she was in labour, she brought forth; before her time came to be delivered, she brought forth a man child.", "bbe": "Before her pains came, she gave birth; before her pains, she gave birth to a man-child.", "geneva": "Before she trauailed, she brought foorth: and before her paine came, she was deliuered of a man childe.", "wycliffe": "Bifor that sche trauelide of child, sche childide; bifor that the sorewe of hir child beryng cam, sche childide a sone.", "rotherham": "Before she travaileth, she hath brought forth,—Before her pains come to her, she hath given birth to a man-child!", "darby": "Before she travailed, she brought forth; before her pain came, she was delivered of a man-child.", "twenty": "", "jps": "Before she travailed, she brought forth; before her pain came, she was delivered of a man-child.", "acv": "Before she travailed, she brought forth. Before her pain came, she was delivered of a man-child.", "anderson": "", "haweis": "", "noyes": "Before she was in travail, she brought forth, Before her pangs came, she was delivered of a son.", "webster": "Before she travailed, she brought forth; before her pain came, she was delivered of a male child.", "vulgate": "antequam parturiret peperit antequam veniret partus eius peperit masculum;", "brenton": "Before she that travailed brought forth, before the travail-pain came on, she escaped it and brought forth a male."}}, {"v": 8, "ref": "66:8", "o": "מִֽי שָׁמַ֣ע כָּ/זֹ֗את מִ֤י רָאָה֙ כָּ/אֵ֔לֶּה הֲ/י֤וּחַל אֶ֨רֶץ֙ בְּ/י֣וֹם אֶחָ֔ד אִם יִוָּ֥לֵֽד גּ֖וֹי פַּ֣עַם אֶחָ֑ת כִּֽי חָ֛לָה גַּם יָלְדָ֥ה צִיּ֖וֹן אֶת בָּנֶֽי/הָ", "en": {"kjv": "Who hath heard such a thing? who hath seen such things? Shall the earth be made to bring forth in one day? or shall a nation be born at once? for as soon as Zion travailed, she brought forth her children.", "web": "Who has heard such a thing? who has seen such things? Shall a land be born in one day? shall a nation be born at once? for as soon as Zion travailed, she gave birth to her children.", "bsb": "Who has heard of such as this? Who has seen such things? Can a country be born in a day or a nation be delivered in an instant? Yet as soon as Zion was in labor, she gave birth to her children.", "asv": "Who hath heard such a thing? who hath seen such things? Shall a land be born in one day? shall a nation be brought forth at once? for as soon as Zion travailed, she brought forth her children.", "ylt": "Who hath heard anything like this? Who hath seen anything like these? Is earth caused to bring forth in one day? Born is a nation at once? For she hath been pained, Zion also hath borne her sons.", "dra": "Who hath ever heard such a thing? and who hath seen the like to this? shall the earth bring forth in one day? or shall a nation be brought forth at once, because Sion hath been in labour, and hath brought forth her children?", "bbe": "When has such a story come to men's ears? who has seen such things? will a land come to birth in one day? will a nation be given birth in a minute? For when Zion's pains came on her, she gave birth to her children straight away.", "geneva": "Who hath heard such a thing? who hath seene such things? shall ye earth be brought forth in one day? or shall a nation be borne at once? for assoone as Zion trauailed, she brought foorth her children.", "wycliffe": "Who herde euere suche a thing, and who siy a thing lijk this? Whether the erthe schal trauele of child in o dai, ether whether a folk schal be childide togidere? For whi Sion trauelede of child, and childide hir sones.", "rotherham": "Who hath heard the like of this? Who hath seen the like of these things? Can a land, be made to bring forth in one day? Or a nation, be born, at one time? As soon as she travaileth, Zion hath also given birth to her children.", "darby": "Who hath heard such a thing? who hath seen such things? Can a land be made to bring forth in one day? shall a nation be born at once? For as soon as Zion travailed, she brought forth her sons.", "twenty": "", "jps": "Who hath heard such a thing? Who hath seen such things? Is a land born in one day? Is a nation brought forth at once? For as soon as Zion travailed, she brought forth her children.", "acv": "Who has heard such a thing? Who has seen such things? Shall a land be born in one day? Shall a nation be brought forth at once? For as soon as Zion travailed, she brought forth her sons.", "anderson": "", "haweis": "", "noyes": "Who hath heard such a thing? Who hath seen such things? Is a country brought forth in a day? Is a nation born at once? For as soon as Zion was in travail, she brought forth her children.", "webster": "Who hath heard such a thing? who hath seen such things? shall the earth be made to bring forth in one day? [or] shall a nation be born at once? for as soon as Zion travailed, she brought forth her children.", "vulgate": "quis audivit umquam tale et quis vidit huic simile numquid parturiet terra in die una aut parietur gens simul quia parturivit et peperit Sion filios suos;", "brenton": "Who has heard such a thing? and who has seen after this manner? Has the earth travailed in one day? or has even a nation been born at once, that Sion has travailed, and brought forth her children?"}}, {"v": 9, "ref": "66:9", "o": "הַ/אֲנִ֥י אַשְׁבִּ֛יר וְ/לֹ֥א אוֹלִ֖יד יֹאמַ֣ר יְהוָ֑ה אִם אֲנִ֧י הַ/מּוֹלִ֛יד וְ/עָצַ֖רְתִּי אָמַ֥ר אֱלֹהָֽיִ/ךְ", "en": {"kjv": "Shall I bring to the birth, and not cause to bring forth? saith the Lord: shall I cause to bring forth, and shut the womb? saith thy God.", "web": "Shall I bring to the birth, and not cause to be delivered?” says Yahweh: “shall I who cause to give birth shut the womb?” says your God.", "bsb": "Shall I bring a baby to the point of birth and not deliver it?” says the LORD. “Or will I who deliver close the womb?” says your God.", "asv": "Shall I bring to the birth, and not cause to bring forth? saith Jehovah: shall I that cause to bring forth shut the womb? saith thy God.", "ylt": "`Do I bring to the birth, And not cause to bring forth?' saith Jehovah, `Am not I He who is causing to beget? I have also restrained,' said thy God.", "dra": "Shall not I that make others to bring forth children, myself bring forth, saith the Lord? shall I, that give generation to others, be barren, saith the Lord thy God?", "bbe": "Will I by whom the birth was started, not make it complete? says the Lord. Will I who make children come to birth, let them be kept back? says your God.", "geneva": "Shall I cause to trauaile, and not bring forth? shall I cause to bring forth, and shall be baren, saith thy God?", "wycliffe": "Whether that Y `my silf that make othere to bere child, schal not ber child? seith the Lord. Whether Y that yyue generacioun to othere men, schal be bareyn? seith thi Lord God.", "rotherham": "Could, I, bring to the birth and not cause to bring forth? saith Yahweh. Or, I, be causing to bring forth and then prevent? Saith thy God.", "darby": "Shall I bring to the birth, and not cause to bring forth? saith Jehovah; I who cause to bring forth, shall I shut [the womb]? saith thyGod.", "twenty": "", "jps": "Shall I bring to the birth, and not cause to bring forth? saith HaShem; shall I that cause to bring forth shut the womb? saith thy G-d.", "acv": "Shall I bring to the birth, and not cause to bring forth? says Jehovah. Shall I who cause to bring forth shut the womb? says thy God.", "anderson": "", "haweis": "", "noyes": "Shall I bring to the birth, and not cause to bring forth, saith Jehovah; Shall I, who beget, restrain the birth? saith thy God.", "webster": "Shall I bring to the birth, and not cause to bring forth? saith the LORD: shall I cause to bring forth, and shut [the womb]? saith thy God.", "vulgate": "numquid ego qui alios parere facio ipse non pariam dicit Dominus si ego qui generationem ceteris tribuo sterilis ero ait Dominus Deus tuus;", "brenton": "But I have raised this expectation, yet thou hast not remembered me, saith the Lord: behold, have not I made the bearing and barren woman? saith thy God."}}, {"v": 10, "ref": "66:10", "o": "שִׂמְח֧וּ אֶת יְרוּשָׁלִַ֛ם וְ/גִ֥ילוּ בָ֖/הּ כָּל אֹהֲבֶ֑י/הָ שִׂ֤ישׂוּ אִתָּ/הּ֙ מָשׂ֔וֹשׂ כָּל הַ/מִּֽתְאַבְּלִ֖ים עָלֶֽי/הָ", "en": {"kjv": "Rejoice ye with Jerusalem, and be glad with her, all ye that love her: rejoice for joy with her, all ye that mourn for her:", "web": "“Rejoice with Jerusalem, and be glad for her, all you who love her: rejoice for joy with her, all you who mourn over her;", "bsb": "Be glad for Jerusalem and rejoice over her, all who love her. Rejoice greatly with her, all who mourn over her,", "asv": "Rejoice ye with Jerusalem, and be glad for her, all ye that love her: rejoice for joy with her, all ye that mourn over her;", "ylt": "Rejoice ye with Jerusalem, And be glad in her, all ye loving her, Rejoice ye with her for joy, All ye are mourning for her,", "dra": "Rejoice with Jerusalem, and be glad with her, all you that love her: rejoice for joy with her, all you that mourn for her.", "bbe": "Have joy with Jerusalem, and be glad with her, all you her lovers: take part in her joy, all you who are sorrowing for her:", "geneva": "Reioyce ye with Ierusalem, and be gladde with her, all ye that loue her: reioyce for ioy with her, all ye that mourne for her,", "wycliffe": "Be ye glad with Jerusalem, and alle ye that louen that, make ful out ioye ther ynne; alle ye that mourenen on that Jerusalem, make ye ioye with it in ioie;", "rotherham": "Rejoice ye with Jerusalem, and exult over her All ye who love her,—Joy with her right joyfully, All ye who used to mourn over her:", "darby": "Rejoice with Jerusalem, and be glad for her, all ye that love her; rejoice for joy with her, all ye that mourn over her:", "twenty": "", "jps": "Rejoice ye with Jerusalem, and be glad with her, all ye that love her; rejoice for joy with her, all ye that mourn for her;", "acv": "Rejoice ye with Jerusalem, and be glad for her, all ye who love her. Rejoice for joy with her, all ye who mourn over her,", "anderson": "", "haweis": "", "noyes": "Rejoice ye with Jerusalem, And exult for her, all ye that love her! Be very joyful with her, all ye that mourn for her!", "webster": "Rejoice ye with Jerusalem, and be glad with her, all ye that love her: rejoice for joy with her, all ye that mourn for her:", "vulgate": "laetamini cum Hierusalem et exultate in ea omnes qui diligitis eam gaudete cum ea gaudio universi qui lugetis super eam;", "brenton": "Rejoice, O Jerusalem, and all ye that love her hold in her a general assembly: rejoice greatly with her, all that now mourn over her:"}}, {"v": 11, "ref": "66:11", "o": "לְמַ֤עַן תִּֽינְקוּ֙ וּ/שְׂבַעְתֶּ֔ם מִ/שֹּׁ֖ד תַּנְחֻמֶ֑י/הָ לְמַ֧עַן תָּמֹ֛צּוּ וְ/הִתְעַנַּגְתֶּ֖ם מִ/זִּ֥יז כְּבוֹדָֽ/הּ", "en": {"kjv": "That ye may suck, and be satisfied with the breasts of her consolations; that ye may milk out, and be delighted with the abundance of her glory.", "web": "that you may nurse and be satisfied at the comforting breasts; that you may drink deeply, and be delighted with the abundance of her glory.”", "bsb": "so that you may nurse and be satisfied at her comforting breasts; you may drink deeply and delight yourselves in her glorious abundance.", "asv": "that ye may suck and be satisfied with the breasts of her consolations; that ye may milk out, and be delighted with the abundance of her glory.", "ylt": "So that ye suck, and have been satisfied, From the breast of her consolations, So that ye wring out, and have delighted yourselves From the abundance of her honour.", "dra": "That you may suck, and be filled with the breasts of her consolations: that you may milk out, and flow with delights, from the abundance of her glory.", "bbe": "So that you may take of the comfort flowing from her breasts, and be delighted with the full measure of her glory.", "geneva": "That ye may sucke and be satisfied with the brestes of her consolation: that ye may milke out and be delited with ye brightnes of her glorie.", "wycliffe": "that bothe ye souke, and be fillid of the tetis and coumfort therof, that ye mylke, and flowe in delicis, of al maner glorie therof.", "rotherham": "That ye may draw to satisfaction out of the fountain of her consolations,—That ye may drain out and get exquisite delight from the abundance of her glory.", "darby": "because ye shall suck, and be satisfied with the breasts of her consolations; because ye shall drink out, and be delighted with the abundance of her glory.", "twenty": "", "jps": "That ye may suck, and be satisfied with the breast of her consolations; that ye may drink deeply with delight of the abundance of her glory.", "acv": "that ye may nurse and be satisfied with the breasts of her consolations, that ye may get milk out, and be delighted with the abundance of her glory.", "anderson": "", "haweis": "", "noyes": "That ye may suck, and be satisfied, from the breast of her consolations, That ye may suck and be delighted with the fulness of her glory.", "webster": "That ye may suck, and be satisfied with the breasts of her consolations; that ye may draw milk, and be delighted with the abundance of her glory.", "vulgate": "ut sugatis et repleamini ab ubere consolationis eius ut mulgeatis et deliciis affluatis ab omnimoda gloria eius;", "brenton": "that ye may suck, and be satisfied with the breast of her consolation; that ye may milk out, and delight yourselves with the influx of her glory."}}, {"v": 12, "ref": "66:12", "o": "כִּֽי כֹ֣ה אָמַ֣ר יְהוָ֗ה הִנְ/נִ֣י נֹטֶֽה אֵ֠לֶי/הָ כְּ/נָהָ֨ר שָׁל֜וֹם וּ/כְ/נַ֧חַל שׁוֹטֵ֛ף כְּב֥וֹד גּוֹיִ֖ם וִֽ/ינַקְתֶּ֑ם עַל צַד֙ תִּנָּשֵׂ֔אוּ וְ/עַל בִּרְכַּ֖יִם תְּשָׁעֳשָֽׁעוּ", "en": {"kjv": "For thus saith the Lord, Behold, I will extend peace to her like a river, and the glory of the Gentiles like a flowing stream: then shall ye suck, ye shall be borne upon her sides, and be dandled upon her knees.", "web": "For thus says Yahweh, “Behold, I will extend peace to her like a river, and the glory of the nations like an overflowing stream: and you will nurse. You will be carried on her side, and will be dandled on her knees.", "bsb": "For this is what the LORD says: “I will extend peace to her like a river, and the wealth of nations like a flowing stream; you will nurse and be carried on her arm, and bounced upon her knees.", "asv": "For thus saith Jehovah, Behold, I will extend peace to her like a river, and the glory of the nations like an overflowing stream: and ye shall suck thereof; ye shall be borne upon the side, and shall be dandled upon the knees.", "ylt": "For thus said Jehovah: `Lo, I am stretching out to her peace as a river, And as an overflowing stream the honour of nations, And ye have sucked, on the side ye are carried, And on the knees ye are dandled.", "dra": "For thus saith the Lord: Behold I will bring upon her as it were a river of peace, and as an overflowing torrent the glory of the Gentiles, which you shall suck; you shall be carried at the breasts, and upon the knees they shall caress you.", "bbe": "For the Lord says, See, I will make her peace like a river, and the glory of the nations like an overflowing stream, and she will take her children in her arms, gently caring for them on her knees.", "geneva": "For thus saith the Lord, Beholde, I will extend peace ouer her like a flood, and the glorie of the Gentiles like a flowing streame: then shall ye sucke, ye shall be borne vpon her sides, and be ioyfull vpon her knees.", "wycliffe": "For whi the Lord seith these thingis, Lo! Y schal bowe doun on it, as a flood of pees, and as a flowynge streem the glorie of hethene men, which ye schulen souke; ye schulen be borun at tetis, and on knees thei schulen speke plesauntly to you.", "rotherham": "For, thus, saith Yahweh,—Behold me! extending unto her like a river, prosperity, And as a torrent o’erflowing, the glory of the nations. That ye may draw it forth—Upon the side, shall ye be carried, and Upon the knees, shall ye be caressed:", "darby": "For thus saith Jehovah: Behold, I will extend peace to her like a river, and the glory of the nations like an overflowing torrent; and ye shall suck, ye shall be carried upon the side, and be dandled upon the knees.", "twenty": "", "jps": "For thus saith HaShem: Behold, I will extend peace to her like a river, and the wealth of the nations like an overflowing stream, and ye shall suck thereof: ye shall be borne upon the side, and shall be dandled upon the knees.", "acv": "For thus says Jehovah, Behold, I will extend peace to her like a river, and the glory of the nations like an overflowing stream. And ye shall nurse thereof. Ye shall be borne upon the side, and shall be dandled upon the knees.", "anderson": "", "haweis": "", "noyes": "For thus saith Jehovah: Behold, I will bring prosperity to her like a river, And the wealth of the nations like an overflowing stream; Ye shall suck at the breast, Ye shall be carried on the arm, And on the knees shall ye be dandled.", "webster": "For thus saith the LORD, Behold, I will extend peace to her like a river, and the glory of the Gentiles like a flowing stream: then shall ye suck, ye shall be borne upon [her] sides, and be dandled upon [her] knees.", "vulgate": "quia haec dicit Dominus ecce ego declinabo super eam quasi fluvium pacis et quasi torrentem inundantem gloriam gentium quam sugetis ad ubera portabimini et super genua blandientur vobis;", "brenton": "For thus saith the Lord, Behold, I turn toward them as a river of peace, and as a torrent bringing upon them in a flood the glory of the Gentiles: their children shall be borne upon the shoulders, and comforted on the knees."}}, {"v": 13, "ref": "66:13", "o": "כְּ/אִ֕ישׁ אֲשֶׁ֥ר אִמּ֖/וֹ תְּנַחֲמֶ֑/נּוּ כֵּ֤ן אָֽנֹכִי֙ אֲנַ֣חֶמְ/כֶ֔ם וּ/בִ/ירֽוּשָׁלִַ֖ם תְּנֻחָֽמוּ", "en": {"kjv": "As one whom his mother comforteth, so will I comfort you; and ye shall be comforted in Jerusalem.", "web": "As one whom his mother comforts, so will I comfort you; and you will be comforted in Jerusalem.”", "bsb": "As a mother comforts her son, so will I comfort you, and you will be consoled over Jerusalem.”", "asv": "As one whom his mother comforteth, so will I comfort you; and ye shall be comforted in Jerusalem.", "ylt": "As one whom his mother comforteth, so do I comfort you, Yea, in Jerusalem ye are comforted.", "dra": "As one whom the mother caresseth, so will I comfort you, and you shall be comforted in Jerusalem.", "bbe": "As to one who is comforted by his mother, so will I give you comfort: and you will be comforted in Jerusalem.", "geneva": "As one whom his mother comforteth, so will I comfort you, and ye shall be comforted in Ierusalem.", "wycliffe": "As if a modir spekith faire to ony child, so Y schal coumforte you, and ye schulen be coumfortid in Jerusalem.", "rotherham": "As one whom, his mother, consoleth, So, will, I, console you, And in Jerusalem, shall ye be consoled.", "darby": "As one whom his mother comforteth, so will I comfort you; and ye shall be comforted in Jerusalem.", "twenty": "", "jps": "As one whom his mother comforteth, so will I comfort you; and ye shall be comforted in Jerusalem.", "acv": "As one whom his mother comforts, so I will comfort you, and ye shall be comforted in Jerusalem.", "anderson": "", "haweis": "", "noyes": "As one whom his mother comforteth, So will I comfort you; And in Jerusalem shall ye be comforted.", "webster": "As one whom his mother comforteth, so will I comfort you; and ye shall be comforted in Jerusalem.", "vulgate": "quomodo si cui mater blandiatur ita ego consolabor vos et in Hierusalem consolabimini;", "brenton": "As if his mother should comfort one, so will I also comfort you; and ye shall be comforted in Jerusalem."}}, {"v": 14, "ref": "66:14", "o": "וּ/רְאִיתֶם֙ וְ/שָׂ֣שׂ לִבְּ/כֶ֔ם וְ/עַצְמוֹתֵי/כֶ֖ם כַּ/דֶּ֣שֶׁא תִפְרַ֑חְנָה וְ/נוֹדְעָ֤ה יַד יְהוָה֙ אֶת עֲבָדָ֔י/ו וְ/זָעַ֖ם אֶת אֹיְבָֽי/ו", "en": {"kjv": "And when ye see this, your heart shall rejoice, and your bones shall flourish like an herb: and the hand of the Lord shall be known toward his servants, and his indignation toward his enemies.", "web": "You will see it, and your heart shall rejoice, and your bones shall flourish like the tender grass: and the hand of Yahweh shall be known toward his servants; and he will have indignation against his enemies.", "bsb": "When you see, you will rejoice, and you will flourish like grass; then the hand of the LORD will be revealed to His servants, but His wrath will be shown to His enemies.", "asv": "And ye shall see it, and your heart shall rejoice, and your bones shall flourish like the tender grass: and the hand of Jehovah shall be known toward his servants; and he will have indignation against his enemies.", "ylt": "And ye have seen, and rejoiced hath your heart, And your bones as tender grass do flourish, And the hand of Jehovah hath been known unto His servants, And He hath been indignant with His enemies.", "dra": "You shall see and your heart shall rejoice, and your bones shall flourish like an herb, and the hand of the Lord shall be known to his servants, and he shall be angry with his enemies.", "bbe": "And you will see it and your heart will be glad, and your bones will get new strength, like young grass: and the hand of the Lord will be seen at work for his servants, and his wrath against his haters.", "geneva": "And when ye see this, your hearts shall reioyce, and your bones shall flourish like an herbe: and the hand of the Lord shall be knowen among his seruants, and his indignation against his enemies.", "wycliffe": "Ye schulen se, and youre herte schal haue ioie, and youre boonys schulen buriowne as an erbe. And the hond of the Lord schal be knowun in hise seruauntis, and he schal haue indignacioun to hise enemyes.", "rotherham": "As soon as ye have seen it, your heart, shall be joyful, And your bones, like green herbage, shall thrive,—So shall be known The hand of Yahweh with his servants, But indignation with his foes!", "darby": "And ye shall see [this], and your heart shall rejoice, and your bones shall flourish like the grass; and the hand of Jehovah shall be known toward his servants, and he will have indignation toward his enemies.", "twenty": "", "jps": "And when ye see this, your heart shall rejoice, and your bones shall flourish like young grass; and the hand of HaShem shall be known toward His servants, and He will have indignation against His enemies.", "acv": "And ye shall see, and your heart shall rejoice, and your bones shall flourish like the tender grass. And the hand of Jehovah shall be known toward his servants, and he will have indignation against his enemies.", "anderson": "", "haweis": "", "noyes": "Ye shall see, and your heart shall rejoice, And your bones shall flourish like a green plant, And the hand of Jehovah shall be manifested to his servants, And be moved with indignation against his enemies.", "webster": "And when ye see [this], your heart shall rejoice, and your bones shall flourish like an herb: and the hand of the LORD shall be known towards his servants, and [his] indignation towards his enemies.", "vulgate": "videbitis et gaudebit cor vestrum et ossa vestra quasi herba germinabunt et cognoscetur manus Domini servis eius et indignabitur inimicis suis;", "brenton": "And ye shall see, and your heart shall rejoice, and your bones shall thrive like grass: and the hand of the Lord shall be known to them that fear him, and he shall threaten the disobedient."}}, {"v": 15, "ref": "66:15", "o": "כִּֽי הִנֵּ֤ה יְהוָה֙ בָּ/אֵ֣שׁ יָב֔וֹא וְ/כַ/סּוּפָ֖ה מַרְכְּבֹתָ֑י/ו לְ/הָשִׁ֤יב בְּ/חֵמָה֙ אַפּ֔/וֹ וְ/גַעֲרָת֖/וֹ בְּ/לַהֲבֵי אֵֽשׁ", "en": {"kjv": "For, behold, the Lord will come with fire, and with his chariots like a whirlwind, to render his anger with fury, and his rebuke with flames of fire.", "web": "For, behold, Yahweh will come with fire, and his chariots shall be like the whirlwind; to render his anger with fierceness, and his rebuke with flames of fire.", "bsb": "For behold, the LORD will come with fire— His chariots are like a whirlwind— to execute His anger with fury and His rebuke with flames of fire.", "asv": "For, behold, Jehovah will come with fire, and his chariots shall be like the whirlwind; to render his anger with fierceness, and his rebuke with flames of fire.", "ylt": "For, lo, Jehovah in fire cometh, And as a hurricane His chariots, To refresh in fury His anger, And His rebuke in flames of fire.", "dra": "For behold the Lord will come with fire, and his chariots are like a whirlwind, to render his wrath in indignation, and his rebuke with flames of fire.", "bbe": "For the Lord is coming with fire, and his war-carriages will be like the storm-wind; to give punishment in the heat of his wrath, and his passion is like flames of fire.", "geneva": "For beholde, the Lord will come with fire, and his charets like a whirlewinde, that he may recompence his anger with wrath, and his indignation with the flame of fire.", "wycliffe": "For lo! the Lord schal come in fier, and as a whirlwynd hise charis, to yelde in indignacioun hise strong veniaunce, and his blamyng in the flawme of fier.", "rotherham": "For lo! Yahweh, with fire, doth come, And like a storm-wind, [are] his chariots,—To render with fury, his anger, And his rebuke with flames of fire.", "darby": "For behold, Jehovah will come with fire, and his chariots like a whirlwind, to render his anger with fury, and his rebuke with flames of fire.", "twenty": "", "jps": "For, behold, HaShem will come in fire, and His chariots shall be like the whirlwind; to render His anger with fury, and His rebuke with flames of fire.", "acv": "For, behold, Jehovah will come with fire, and his chariots shall be like the whirlwind, to render his anger with fierceness, and his rebuke with flames of fire.", "anderson": "", "haweis": "", "noyes": "For behold, Jehovah cometh with fire, Like a whirlwind are his chariots, To breathe forth his anger in a glowing heat, And his rebuke in flames of fire.", "webster": "For behold, the LORD will come with fire, and with his chariots like a whirlwind, to render his anger with fury, and his rebuke with flames of fire.", "vulgate": "quia ecce Dominus in igne veniet et quasi turbo quadrigae eius reddere in indignatione furorem suum et increpationem suam in flamma ignis;", "brenton": "For, behold, the Lord will come as fire, and his chariots as a storm, to render his vengeance with wrath, and his rebuke with a flame of fire."}}, {"v": 16, "ref": "66:16", "o": "כִּ֤י בָ/אֵשׁ֙ יְהוָ֣ה נִשְׁפָּ֔ט וּ/בְ/חַרְבּ֖/וֹ אֶת כָּל בָּשָׂ֑ר וְ/רַבּ֖וּ חַֽלְלֵ֥י יְהוָֽה", "en": {"kjv": "For by fire and by his sword will the Lord plead with all flesh: and the slain of the Lord shall be many.", "web": "For by fire will Yahweh execute judgment, and by his sword, on all flesh; and the slain of Yahweh shall be many.", "bsb": "For by fire and by His sword, the LORD will execute judgment on all flesh, and many will be slain by the LORD.", "asv": "For by fire will Jehovah execute judgment, and by his sword, upon all flesh; and the slain of Jehovah shall be many.", "ylt": "For by fire and by His sword, Doth Jehovah do judgment with all flesh. And many have been Jehovah's pierced ones.'", "dra": "For the Lord shall judge by fire, and by his sword unto all flesh, and the slain of the Lord shall be many.", "bbe": "For with fire and sword will the Lord come, judging all the earth, and his sword will be on all flesh: and great numbers will be put to death by him.", "geneva": "For the Lord will iudge with fire, and with his sworde all flesh, and the slaine of the Lord shall be many.", "wycliffe": "For whi the Lord schal deme in fier, and in hys swerd to ech fleisch; and slayn men of the Lord schulen be multiplied,", "rotherham": "For, by fire, will Yahweh enter into judgment, And by his sword, with all flesh,—And many shall be the slain of Yahweh.", "darby": "For by fire and by his sword will Jehovah enter into judgment with all flesh: and the slain of Jehovah shall be many.", "twenty": "", "jps": "For by fire will HaShem contend, and by His sword with all flesh; and the slain of HaShem shall be many.", "acv": "For by fire Jehovah will execute judgment, and by his sword, upon all flesh, and the slain of Jehovah shall be many.", "anderson": "", "haweis": "", "noyes": "For with fire will Jehovah contend, And with his sword, with all flesh, And many shall be the slain of Jehovah.", "webster": "For by fire and by his sword will the LORD plead with all flesh: and the slain of the LORD shall be many.", "vulgate": "quia in igne Dominus diiudicatur et in gladio suo ad omnem carnem et multiplicabuntur interfecti a Domino;", "brenton": "For with the fire of the Lord all the earth shall be judged, and all flesh with his sword: many shall be slain by the Lord."}}, {"v": 17, "ref": "66:17", "o": "הַ/מִּתְקַדְּשִׁ֨ים וְ/הַ/מִּֽטַּהֲרִ֜ים אֶל הַ/גַּנּ֗וֹת אַחַ֤ר אחד אַחַת֙ בַּ/תָּ֔וֶךְ אֹֽכְלֵי֙ בְּשַׂ֣ר הַ/חֲזִ֔יר וְ/הַ/שֶּׁ֖קֶץ וְ/הָ/עַכְבָּ֑ר יַחְדָּ֥ו יָסֻ֖פוּ נְאֻם יְהוָֽה", "en": {"kjv": "They that sanctify themselves, and purify themselves in the gardens behind one tree in the midst, eating swine’s flesh, and the abomination, and the mouse, shall be consumed together, saith the Lord.", "web": "“Those who sanctify themselves and purify themselves to go to the gardens, behind one in the midst, eating pig’s flesh, and the abomination, and the mouse, they shall come to an end together,” says Yahweh.", "bsb": "“Those who consecrate and purify themselves to enter the groves—to follow one in the center of those who eat the flesh of swine and vermin and rats—will perish together,” declares the LORD.", "asv": "They that sanctify themselves and purify themselves to go unto the gardens, behind one in the midst, eating swine’s flesh, and the abomination, and the mouse, they shall come to an end together, saith Jehovah.", "ylt": "Those sanctifying and cleansing themselves at the gardens, After Ahad in the midst, Eating flesh of the sow, And of the abomination, and of the mouse, Together are consumed, An affirmation of Jehovah.", "dra": "They that were sanctified, thought themselves clean in the gardens behind the gate within, they that did eat swine's flesh, and the abomination, and the mouse: they shall be consumed together, saith the Lord.", "bbe": "As for those who keep themselves separate, and make themselves clean in the gardens, going after one in the middle, taking pig's flesh for food, and other disgusting things, such as the mouse: their works and their thoughts will come to an end together, says the Lord.", "geneva": "They that sanctifie themselues, and purifie themselues in the gardens behinde one tree in the middes eating swines flesh, and such abomination, euen the mouse, shall be consumed together, sayeth the Lord.", "wycliffe": "that weren halewid, and gessiden hem cleene, in gardyns aftir o yate with ynne; that eten swynes fleisch, and abhomynacioun, and a mows, thei schulen be waastid togidere, seith the Lord.", "rotherham": "They who hallow themselves and purify themselves for the gardens, Behind a certain thing in the midst, Who eat the flesh of swine and the abomination, and the mouse, Together, shall be cut off—Declareth Yahweh.", "darby": "They that sanctify themselves, and purify themselves in the gardens behind one in the midst; that eat swine's flesh, and the abomination, and the mouse, shall perish together, saith Jehovah.", "twenty": "", "jps": "They that sanctify themselves and purify themselves to go unto the gardens, behind one in the midst, eating swine's flesh, and the detestable thing, and the mouse, shall be consumed together, saith HaShem.", "acv": "Those who sanctify themselves and purify themselves to go to the gardens, behind one in the midst, eating swine's flesh, and the abomination, and the mouse, they shall come to an end together, says Jehovah.", "anderson": "", "haweis": "", "noyes": "They who sanctify and purify themselves in the groves, Following one in the midst, Who eat swine’s flesh, and the abomination, and the mouse. They shall all perish together, saith Jehovah.", "webster": "They that sanctify themselves, and purify themselves in the gardens behind one [tree] in the midst, eating swine's flesh, and the abomination, and the mouse, shall be consumed together, saith the LORD.", "vulgate": "qui sanctificabantur et mundos se putabant in hortis post unam intrinsecus qui comedebant carnem suillam et abominationem et murem simul consumentur dicit Dominus;", "brenton": "They that sanctify themselves and purify themselves in the gardens, and eat swine's flesh in the porches, and the abominations, and the mouse, shall be consumed together, saith the Lord."}}, {"v": 18, "ref": "66:18", "o": "וְ/אָנֹכִ֗י מַעֲשֵׂי/הֶם֙ וּ/מַחְשְׁבֹ֣תֵי/הֶ֔ם בָּאָ֕ה לְ/קַבֵּ֥ץ אֶת כָּל הַ/גּוֹיִ֖ם וְ/הַ/לְּשֹׁנ֑וֹת וּ/בָ֖אוּ וְ/רָא֥וּ אֶת כְּבוֹדִֽ/י", "en": {"kjv": "For I know their works and their thoughts: it shall come, that I will gather all nations and tongues; and they shall come, and see my glory.", "web": "“For I know their works and their thoughts: the time comes, that I will gather all nations and languages; and they shall come, and shall see my glory.", "bsb": "“And I, knowing their deeds and thoughts, am coming to gather all nations and tongues, and they will come and see My glory.", "asv": "For Iknowtheir works and their thoughts: the time cometh, that I will gather all nations and tongues; and they shall come, and shall see my glory.", "ylt": "And I--their works and their thoughts, I come to gather all the nations and tongues, And they have come and seen My honour.", "dra": "But I know their works, and their thoughts: I come that I may gather them together with all nations and tongues: and they shall come and shall see my glory.", "bbe": "And I am coming to get together all nations and tongues: and they will come and will see my glory.", "geneva": "For I will visite their workes, and their imaginations: for it shall come that I will gather all nations, and tongues, and they shall come, and see my glorie.", "wycliffe": "Forsothe Y come to gadere togidere the werkis of hem, and the thouytis of hem, with alle folkis and langagis; and thei schulen come, and schulen se my glorie.", "rotherham": "Because, I, …for their works and their devices, doth it come! …Am about to gather together all nations and tongues,—So shall they come and see my glory.", "darby": "And I, — their works and their thoughts [are before me]. ...[The time] cometh for the gathering of all nations and tongues; and they shall come, and see my glory.", "twenty": "", "jps": "For I know their works and their thoughts; the time cometh, that I will gather all nations and tongues; and they shall come, and shall see My glory.", "acv": "For I know their works and their thoughts. The time comes, that I will gather all nations and tongues, and they shall come, and shall see my glory.", "anderson": "", "haweis": "", "noyes": "For I know their works, and their thoughts; The time cometh to gather all nations and tongues together; They shall come, and behold my glory.", "webster": "For I [know] their works and their thoughts: it shall come, that I will gather all nations and tongues; and they shall come, and see my glory.", "vulgate": "ego autem opera eorum et cogitationes eorum venio ut congregem cum omnibus gentibus et linguis et venient et videbunt gloriam meam;", "brenton": "And I know their works and their imagination. I am going to gather all nations and tongues; and they shall come, and see my glory."}}, {"v": 19, "ref": "66:19", "o": "וְ/שַׂמְתִּ֨י בָ/הֶ֜ם א֗וֹת וְ/שִׁלַּחְתִּ֣י מֵ/הֶ֣ם פְּ֠לֵיטִים אֶֽל הַ/גּוֹיִ֞ם תַּרְשִׁ֨ישׁ פּ֥וּל וְ/ל֛וּד מֹ֥שְׁכֵי קֶ֖שֶׁת תֻּבַ֣ל וְ/יָוָ֑ן הָ/אִיִּ֣ים הָ/רְחֹקִ֗ים אֲשֶׁ֨ר לֹא שָׁמְע֤וּ אֶת שִׁמְעִ/י֙ וְ/לֹא רָא֣וּ אֶת כְּבוֹדִ֔/י וְ/הִגִּ֥ידוּ אֶת כְּבוֹדִ֖/י בַּ/גּוֹיִֽם", "en": {"kjv": "And I will set a sign among them, and I will send those that escape of them unto the nations, to Tarshish, Pul, and Lud, that draw the bow, to Tubal, and Javan, to the isles afar off, that have not heard my fame, neither have seen my glory; and they shall declare my glory among the Gentiles.", "web": "“I will set a sign among them, and I will send such as escape of them to the nations, to Tarshish, Pul, and Lud, who draw the bow, to Tubal and Javan, to the islands afar off, who have not heard my fame, neither have seen my glory; and they shall declare my glory among the nations.", "bsb": "I will establish a sign among them, and I will send survivors from among them to the nations—to Tarshish, Put, and the archers of Lud; to Tubal, Javan, and the islands far away who have not heard of My fame or seen My glory. So they will proclaim My glory among the nations.", "asv": "And I will set a sign among them, and I will send such as escape of them unto the nations, to Tarshish, Pul, and Lud, that draw the bow, to Tubal and Javan, to the isles afar off, that have not heard my fame, neither have seen my glory; and they shall declare my glory among the nations.", "ylt": "And I have set among them a sign, And have sent out of them those escaping unto the nations, (Tarshish, Pul, and Lud, drawing bow, Tubal and Javan, the isles that are far off,) Who have not heard My fame, nor seen Mine honour, And they have declared Mine honour among nations.", "dra": "And I will set a sign among them, and I will send of them that shall be saved, to the Gentiles into the sea, into Africa, and Lydia them that draw the bow: into Italy, and Greece, to the islands afar off, to them that have not heard of me, and have not seen my glory. And they shall declare my glory to the Gentiles:", "bbe": "And I will put a sign among them, and I will send those who are still living to the nations, to Tarshish, Put, and Lud, Meshech and Rosh, Tubal and Javan, to the sea-lands far away, who have not had word of me, or seen my glory; and they will give the knowledge of my glory to the nations.", "geneva": "And I will set a signe among them, and will send those that escape of them, vnto the nations of Tarshish, Pul, and Lud, and to them that drawe the bowe, to Tubal and Tauan, yles afarre off, that haue not heard my fame, neither haue seene my glorie, and they shall declare my glorie among the Gentiles.", "wycliffe": "And Y schal sette a signe in hem, and Y schal sende of hem that ben sauyd to hethene men, in to the see, in to Affrik, and in to Liddia, and to hem that holden arowe, in to Italie, and Greek lond, to ilis fer, to hem that herden not of me, and sien not my glorie. And thei schulen telle my glorie to hethene men,", "rotherham": "Then will I set among them, a sign, And will send, of them such as have escaped unto the nations—Tarshish Pul and Lud that draw the bow, Tubal and Javan,—The Coastlands that are afar off, Who have not heard my fame Nor seen my glory, And they shall tell my glory throughout the nations.", "darby": "And I will set a sign among them, and I will send those that escape of them unto the nations, to Tarshish, Pul, and Lud, that draw the bow; to Tubal and Javan, to the isles afar off, that have not heard my fame, neither have seen my glory: and they shall declare my glory among the nations.", "twenty": "", "jps": "And I will work a sign among them, and I will send such as escape of them unto the nations, to Tarshish, Pul and Lud, that draw the bow, to Tubal and Javan, to the isles afar off, that have not heard My fame, neither have seen My glory; and they shall declare My glory among the nations.", "acv": "And I will set a sign among them, and I will send such as escape of them to the nations, to Tarshish, Pul, and Lud, that draw the bow, to Tubal and Javan, to the isles afar off, who have not heard my fame, nor have seen my glory, and they shall declare my glory among the nations.", "anderson": "", "haweis": "", "noyes": "And I will give a sign among them, And of those that escape I will send to the nations, To Tarshish, Phul, and Lud, who draw the bow, to Tubal and Javan, To the distant coasts, who never heard my name, And who never saw my glory; And they shall declare my glory among the nations.", "webster": "And I will set a sign among them, and I will send those that escape of them to the nations, [to] Tarshish, Pul, and Lud, that draw the bow, [to] Tubal, and Javan, [to] the isles afar off, that have not heard my fame, neither have seen my glory; and they shall declare my glory among the Gentiles.", "vulgate": "et ponam in eis signum et mittam ex eis qui salvati fuerint ad gentes in mari in Africa in Lydia tenentes sagittam in Italiam et Graeciam ad insulas longe ad eos qui non audierunt de me et non viderunt gloriam meam et adnuntiabunt gloriam meam gentibus;", "brenton": "And I will leave a sign upon them, and I will send forth them that have escaped of them to the nations, to Tharsis, and Phud, and Lud, and Mosoch, and to Thobel, and to Greece, and to the isles afar off, to those who have not heard my name, nor seen my glory; and they shall declare my glory among the Gentiles."}}, {"v": 20, "ref": "66:20", "o": "וְ/הֵבִ֣יאוּ אֶת כָּל אֲחֵי/כֶ֣ם מִ/כָּל הַ/גּוֹיִ֣ם מִנְחָ֣ה לַֽ/יהוָ֡ה בַּ/סּוּסִ֡ים וּ֠/בָ/רֶכֶב וּ/בַ/צַּבִּ֨ים וּ/בַ/פְּרָדִ֜ים וּ/בַ/כִּרְכָּר֗וֹת עַ֣ל הַ֥ר קָדְשִׁ֛/י יְרוּשָׁלִַ֖ם אָמַ֣ר יְהוָ֑ה כַּ/אֲשֶׁ֣ר יָבִיאוּ֩ בְנֵ֨י יִשְׂרָאֵ֧ל אֶת הַ/מִּנְחָ֛ה בִּ/כְלִ֥י טָה֖וֹר בֵּ֥ית יְהוָֽה", "en": {"kjv": "And they shall bring all your brethren for an offering unto the Lord out of all nations upon horses, and in chariots, and in litters, and upon mules, and upon swift beasts, to my holy mountain Jerusalem, saith the Lord, as the children of Israel bring an offering in a clean vessel into the house of the Lord.", "web": "They shall bring all your brothers out of all the nations for an offering to Yahweh, on horses, and in chariots, and in litters, and on mules, and on dromedaries, to my holy mountain Jerusalem, says Yahweh, as the children of Israel bring their offering in a clean vessel into Yahweh’s house.", "bsb": "And they will bring all your brothers from all the nations as a gift to the LORD on horses and chariots and wagons, on mules and camels, to My holy mountain Jerusalem,” says the LORD, “just as the Israelites bring an offering in a clean vessel to the house of the LORD.”", "asv": "And they shall bring all your brethren out of all the nations for an oblation unto Jehovah, upon horses, and in chariots, and in litters, and upon mules, and upon dromedaries, to my holy mountain Jerusalem, saith Jehovah, as the children of Israel bring their oblation in a clean vessel into the house of Jehovah.", "ylt": "And they have brought all your brethren out of all the nations, A present to Jehovah, On horses, and on chariot, and on litters, And on mules, and on dromedaries, Unto My holy mountain Jerusalem, said Jehovah, As the sons of Israel bring the present in a clean vessel, Into the house of Jehovah.", "dra": "And they shall bring all your brethren out of all nations for a gift to the Lord, upon horses, and in chariots, and in litters, and on mules, and in coaches, to my holy mountain Jerusalem, saith the Lord, as if the children of Israel should bring an offering in a clean vessel into the house of the Lord.", "bbe": "And they will take your countrymen out of all the nations for an offering to the Lord, on horses, and in carriages, and in carts, and on asses, and on camels, to my holy mountain Jerusalem, says the Lord, as the children of Israel take their offering in a clean vessel into the house of the Lord.", "geneva": "And they shall bring all your brethren for an offering vnto the Lord out of all nations, vpon horses, and in charets, and in horse litters, and vpon mules, and swift beastes, to Ierusalem mine holy Mountaine, saith the Lord, as the children of Israel, offer in a cleane vessell in the House of the Lord.", "wycliffe": "and thei schulen brynge alle youre britheren of alle folkis a yifte to the Lord, in horsis, and charis, and in literis, and in mulis, and in cartis, to myn hooli hil, Jerusalem, seith the Lord; as if the sones of Israel bryngen a yifte in a cleene vessel in to the hous of the Lord.", "rotherham": "Then shall they bring in all your brethren out of all the nations, As a present unto Yahweh, Upon horses and in chariots and in palanquins and on mules and on dromedaries Unto my holy mountain—Jerusalem, saith Yahweh,—Just as the sons of Israel, bring in their present in a pure vessel, into the house, of Yahweh.", "darby": "And they shall bring all your brethren out of all the nations as an oblation unto Jehovah, upon horses, and in chariots, and in covered waggons, and upon mules, and upon dromedaries, to my holy mountain, to Jerusalem, saith Jehovah, as the children of Israel bring an oblation in a clean vessel into the house of Jehovah.", "twenty": "", "jps": "And they shall bring all your brethren out of all the nations for an offering unto HaShem, upon horses, and in chariots, and in fitters, and upon mules, and upon swift beasts, to My holy mountain Jerusalem, saith HaShem, as the children of Israel bring their offering in a clean vessel into the house of HaShem.", "acv": "And they shall bring all your brothers out of all the nations for an oblation to Jehovah, upon horses, and in chariots, and in litters, and upon mules, and upon dromedaries, to my holy mountain Jerusalem, says Jehovah, as the sons of Israel bring their oblation in a clean vessel into the house of Jehovah.", "anderson": "", "haweis": "", "noyes": "And they shall bring all your brethren From all the nations, an offering to Jehovah, Upon horses, and in chariots, and in litters, and upon mules and dromedaries, To my holy mountain, Jerusalem, saith Jehovah, As the sons of Israel bring their gifts In pure vessels to the house of Jehovah.", "webster": "And they shall bring all your brethren [for] an offering to the LORD out of all nations upon horses, and in chariots, and in litters, and upon mules, and upon swift beasts, to my holy mountain Jerusalem, saith the LORD, as the children of Israel bring an offering in a clean vessel into the house of the LORD.", "vulgate": "et adducent omnes fratres vestros de cunctis gentibus donum Domino in equis et in quadrigis et in lecticis et in mulis et in carrucis ad montem sanctum meum Hierusalem dicit Dominus quomodo si inferant filii Israhel munus in vase mundo in domum Domini;", "brenton": "And they shall bring your brethren out of all nations for a gift to the Lord with horses, and chariots, in litters drawn by mules with awnings, to the holy city Jerusalem, said the Lord, as though the children of Israel should bring their sacrifices to me with psalms into the house of the Lord."}}, {"v": 21, "ref": "66:21", "o": "וְ/גַם מֵ/הֶ֥ם אֶקַּ֛ח לַ/כֹּהֲנִ֥ים לַ/לְוִיִּ֖ם אָמַ֥ר יְהוָֽה", "en": {"kjv": "And I will also take of them for priests and for Levites, saith the Lord.", "web": "Of them also will I take for priests and for Levites,” says Yahweh.", "bsb": "“And I will select some of them as priests and Levites,” says the LORD.", "asv": "And of them also will I take for priests and for Levites, saith Jehovah.", "ylt": "And also of them I take for priests, For Levites, said Jehovah.", "dra": "And I will take of them to be priests, and Levites, saith the Lord.", "bbe": "And some of them will I take for priests and Levites, says the Lord.", "geneva": "And I will take of them for Priestes, and for Leuites, saith the Lord.", "wycliffe": "And Y schal take of hem in to preestis and dekenes, seith the Lord.", "rotherham": "And of them also, will I take for priests—for Levites, saith Yahweh,", "darby": "And I will also take of them for priests [and] for Levites, saith Jehovah.", "twenty": "", "jps": "And of them also will I take for the priests and for the Levites, saith HaShem.", "acv": "And of them also I will take for priests and for Levites, says Jehovah.", "anderson": "", "haweis": "", "noyes": "And of them will I also take For priests and for Levites, saith Jehovah.", "webster": "And I will also take of them for priests [and] for Levites, saith the LORD.", "vulgate": "et adsumam ex eis in sacerdotes et in Levitas dicit Dominus;", "brenton": "And I will take of them priests and Levites, saith the Lord."}}, {"v": 22, "ref": "66:22", "o": "כִּ֣י כַ/אֲשֶׁ֣ר הַ/שָּׁמַ֣יִם הַ֠/חֳדָשִׁים וְ/הָ/אָ֨רֶץ הַ/חֲדָשָׁ֜ה אֲשֶׁ֨ר אֲנִ֥י עֹשֶׂ֛ה עֹמְדִ֥ים לְ/פָנַ֖/י נְאֻם יְהוָ֑ה כֵּ֛ן יַעֲמֹ֥ד זַרְעֲ/כֶ֖ם וְ/שִׁמְ/כֶֽם", "en": {"kjv": "For as the new heavens and the new earth, which I will make, shall remain before me, saith the Lord, so shall your seed and your name remain.", "web": "“For as the new heavens and the new earth, which I will make, shall remain before me,” says Yahweh, “so your seed and your name shall remain.", "bsb": "“For just as the new heavens and the new earth, which I will make, will endure before Me,” declares the LORD, “so your descendants and your name will endure.", "asv": "For as the new heavens and the new earth, which I will make, shall remain before me, saith Jehovah, so shall your seed and your name remain.", "ylt": "For, as the new heavens and the new earth that I am making, Are standing before Me, An affirmation of Jehovah! So remain doth your seed and your name.", "dra": "For as the new heavens, and the new earth, which I will make to stand before me, saith the Lord: so shall your seed stand, and your name.", "bbe": "For as the new heaven and the new earth which I will make will be for ever before me, says the Lord, so will your seed and your name be for ever.", "geneva": "For as the newe heauens, and the newe earth which I will make, shall remaine before me, saith the Lord, so shall your seede and your name continue.", "wycliffe": "For as newe heuenes and newe erthe, whiche Y make to stonde bifore me, seith the Lord, so youre seed schal stonde, and youre name.", "rotherham": "For, as the new heavens and the new earth, which I am about to make, are to remain before me, Declareth Yahweh, So, shall remain your seed and your name.", "darby": "For as the new heavens and the new earth which I will make shall remain before me, saith Jehovah, so shall your seed and your name remain.", "twenty": "", "jps": "For as the new heavens and the new earth, which I will make, shall remain before Me, saith HaShem, so shall your seed and your name remain.", "acv": "For as the new heavens and the new earth, which I will make, shall remain before me, says Jehovah, so shall your seed and your name remain.", "anderson": "", "haweis": "", "noyes": "For as the new heavens, And the new earth, which I make, Endure before me, saith Jehovah, So shall your race and your name endure.", "webster": "For as the new heavens and the new earth, which I will make, shall remain before me, saith the LORD, so shall your seed and your name remain.", "vulgate": "quia sicut caeli novi et terra nova quae ego facio stare coram me dicit Dominus sic stabit semen vestrum et nomen vestrum;", "brenton": "For as the new heaven and the new earth, which I make, remain before me, saith the Lord, so shall your seed and your name continue."}}, {"v": 23, "ref": "66:23", "o": "וְ/הָיָ֗ה מִֽ/דֵּי חֹ֨דֶשׁ֙ בְּ/חָדְשׁ֔/וֹ וּ/מִ/דֵּ֥י שַׁבָּ֖ת בְּ/שַׁבַּתּ֑/וֹ יָב֧וֹא כָל בָּשָׂ֛ר לְ/הִשְׁתַּחֲוֺ֥ת לְ/פָנַ֖/י אָמַ֥ר יְהוָֽה", "en": {"kjv": "And it shall come to pass, that from one new moon to another, and from one sabbath to another, shall all flesh come to worship before me, saith the Lord.", "web": "It shall happen, that from one new moon to another, and from one Sabbath to another, shall all flesh come to worship before me,” says Yahweh.", "bsb": "From one New Moon to another and from one Sabbath to another, all mankind will come to worship before Me,” says the LORD.", "asv": "And it shall come to pass, that from one new moon to another, and from one sabbath to another, shall all flesh come to worship before me, saith Jehovah.", "ylt": "And it hath been from month to month, And from sabbath to sabbath, Come do all flesh to bow themselves before Me, Said Jehovah.", "dra": "And there shall be month after month, and sabbath after sabbath: and all flesh shall come to adore before my face, saith the Lord.", "bbe": "And it will be, that from new moon to new moon, and from Sabbath to Sabbath, all flesh will come to give worship before me, says the Lord.", "geneva": "And from moneth to moneth, and from Sabbath to Sabbath shall all flesh come to worship before me, saith the Lord.", "wycliffe": "And a monethe schal be of monethe, and a sabat of sabat; ech man schal come for to worschipe bifore my face, seith the Lord.", "rotherham": "And it shall come to pass, that From one new moon to another, and From one sabbath to another, Shall all flesh, come in, to bow down before me, Saith Yahweh.", "darby": "And it shall come to pass from new moon to new moon, and from sabbath to sabbath, all flesh shall come to worship before me, saith Jehovah.", "twenty": "", "jps": "And it shall come to pass, that from one new moon to another, and from one sabbath to another, shall all flesh come to worship before Me, saith HaShem.", "acv": "And it shall come to pass, that from one new moon to another, and from one sabbath to another, all flesh shall come to worship before me, says Jehovah.", "anderson": "", "haweis": "", "noyes": "And it shall be, from new moon to new moon, And from sabbath to sabbath, That all flesh shall come and worship before me, saith Jehovah.", "webster": "And it shall come to pass, [that] from one new moon to another, and from one sabbath to another, shall all flesh come to worship before me, saith the LORD.", "vulgate": "et erit mensis ex mense et sabbatum ex sabbato veniet omnis caro ut adoret coram facie mea dicit Dominus;", "brenton": "And it shall come to pass from month to month, and from sabbath to sabbath, that all flesh shall come to worship before me in Jerusalem, saith the Lord."}}, {"v": 24, "ref": "66:24", "o": "וְ/יָצְא֣וּ וְ/רָא֔וּ בְּ/פִגְרֵי֙ הָ/אֲנָשִׁ֔ים הַ/פֹּשְׁעִ֖ים בִּ֑/י כִּ֣י תוֹלַעְתָּ֞/ם לֹ֣א תָמ֗וּת וְ/אִשָּׁ/ם֙ לֹ֣א תִכְבֶּ֔ה וְ/הָי֥וּ דֵרָא֖וֹן לְ/כָל בָּשָֽׂר", "en": {"kjv": "And they shall go forth, and look upon the carcases of the men that have transgressed against me: for their worm shall not die, neither shall their fire be quenched; and they shall be an abhorring unto all flesh.", "web": "“They shall go out, and look on the dead bodies of the men who have transgressed against me: for their worm shall not die, neither shall their fire be quenched; and they will be loathsome to all mankind.”", "bsb": "“As they go forth, they will see the corpses of the men who have rebelled against Me; for their worm will never die, their fire will never be quenched, and they will be a horror to all mankind.”", "asv": "And they shall go forth, and look upon the dead bodies of the men that have transgressed against me: for their worm shall not die, neither shall their fire be quenched; and they shall be an abhorring unto all flesh.", "ylt": "And they have gone forth, And looked on the carcases of the men Who are transgressing against me, For their worm dieth not, And their fire is not quenched, And they have been an abhorrence to all flesh!", "dra": "And they shall go out, and see the carcasses of the men that have transgressed against me: their worm shall not die, and their fire shall not be quenched: and they shall be a loathsome sight to all flesh.", "bbe": "And they will go out to see the dead bodies of the men who have done evil against me: for their worm will ever be living, and their fire will never be put out, and they will be a thing of fear to all flesh.", "geneva": "And they shall goe forth, and looke vpon the carkases of the men that haue transgressed against me: for their worme shall not dye, neither shall their fire be quenched, and they shalbe an abhorring vnto all flesh.", "wycliffe": "And thei schulen go out, and schulen se the careyns of men, that trespassiden ayens me; the worm of hem schal not die, and the fier of hem schal not be quenchid; and thei schulen be `til to fillyng of siyt to ech man.", "rotherham": "Then shall they go forth and look upon the dead bodies of the men who had been trespassing against me—For, their worm, shall not die, And, their fire, shall not be quenched; So shall they become an abhorrence to all flesh.", "darby": "And they shall go forth, and look upon the carcases of the men that have transgressed against me: for their worm shall not die, neither shall their fire be quenched; and they shall be an abhorrence unto all flesh.", "twenty": "", "jps": "And they shall go forth, and look upon the carcasses of the men that have rebelled against Me; for their worm shall not die, neither shall their fire be quenched; and they shall be an abhorring unto all flesh.", "acv": "And they shall go forth, and look upon the dead bodies of the men who have transgressed against me. For their worm shall not die, nor shall their fire be quenched, and they shall be an abhorring to all flesh.", "anderson": "", "haweis": "", "noyes": "Then shall they go forth and see The dead bodies of the men that rebelled against me! For their worm shall not die, And their fire shall not be quenched, And they shall be an abhorrence to all flesh.", "webster": "And they shall go forth, and look upon the carcasses of the men that have transgressed against me: for their worm shall not die, neither shall their fire be quenched; and they shall be an abhorring to all flesh.", "vulgate": "et egredientur et videbunt cadavera virorum qui praevaricati sunt in me vermis eorum non morietur et ignis eorum non extinguetur et erunt usque ad satietatem visionis omni carni;", "brenton": "And they shall go forth, and see the carcasses of the men that have transgressed against me: for their worm shall not die, and their fire shall not be quenched; and they shall be a spectacle to all flesh."}}]}]};
window.BOOKS=[{"slug": "mark", "name": "Mark", "file": "Mark.html", "testament": "NT"}, {"slug": "matthew", "name": "Matthew", "file": "Matthew.html", "testament": "NT"}, {"slug": "luke", "name": "Luke", "file": "Luke.html", "testament": "NT"}, {"slug": "john", "name": "John", "file": "John.html", "testament": "NT"}, {"slug": "acts", "name": "Acts", "file": "Acts.html", "testament": "NT"}, {"slug": "romans", "name": "Romans", "file": "Romans.html", "testament": "NT"}, {"slug": "1corinthians", "name": "1 Corinthians", "file": "1Corinthians.html", "testament": "NT"}, {"slug": "philippians", "name": "Philippians", "file": "Philippians.html", "testament": "NT"}, {"slug": "colossians", "name": "Colossians", "file": "Colossians.html", "testament": "NT"}, {"slug": "philemon", "name": "Philemon", "file": "Philemon.html", "testament": "NT"}, {"slug": "hebrews", "name": "Hebrews", "file": "Hebrews.html", "testament": "NT"}, {"slug": "genesis", "name": "Genesis", "file": "Genesis.html", "testament": "OT"}, {"slug": "exodus", "name": "Exodus", "file": "Exodus.html", "testament": "OT"}, {"slug": "leviticus", "name": "Leviticus", "file": "Leviticus.html", "testament": "OT"}, {"slug": "numbers", "name": "Numbers", "file": "Numbers.html", "testament": "OT"}, {"slug": "deuteronomy", "name": "Deuteronomy", "file": "Deuteronomy.html", "testament": "OT"}, {"slug": "ruth", "name": "Ruth", "file": "Ruth.html", "testament": "OT"}, {"slug": "job", "name": "Job", "file": "Job.html", "testament": "OT"}, {"slug": "psalms", "name": "Psalms", "file": "Psalms.html", "testament": "OT"}, {"slug": "isaiah", "name": "Isaiah", "file": "Isaiah.html", "testament": "OT"}, {"slug": "ezekiel", "name": "Ezekiel", "file": "Ezekiel.html", "testament": "OT"}, {"slug": "daniel", "name": "Daniel", "file": "Daniel.html", "testament": "OT"}];
window.ANNOT={"6:9": [{"ref": "6:9", "title": "“Hear but do not understand”", "finding": "Isaiah's commission — a people who hear but do not perceive — is the verse Mark makes the purpose of Jesus' parables (4:12): outsiders are told 'so that seeing they may not see.'", "category": "ot-allusion", "citation": "Isa 6:9-10; cf. Mark 4:12. — mark-origins", "tier": "DEMONSTRABLE"}], "7:14": [{"ref": "7:14", "title": "almah / parthenos — the virgin birth on the Greek", "finding": "'Behold, the almah shall conceive.' Hebrew almah means 'young woman'; the Septuagint renders it parthenos, 'virgin.' Matthew (1:23) builds the virgin birth on the GREEK reading. Julian pressed that Isaiah says nothing of a god born of a virgin.", "category": "source-critical", "citation": "Isa 7:14 עַלְמָה / LXX παρθένος; cf. Matt 1:23. — nt-citation-sources", "tier": "DEMONSTRABLE"}], "9:6": [{"ref": "9:6", "title": "“Unto us a child is born”", "finding": "'For unto us a child is born... and his name shall be called Wonderful Counselor, Mighty God, Everlasting Father, Prince of Peace' — a royal birth-oracle read messianically, and a text later pressed into the debate over Jesus' divinity.", "category": "ot-allusion", "citation": "Isa 9:6-7. — ot-nt-typology", "tier": "STRONG-INFERENCE"}], "27:1": [{"ref": "27:1", "title": "Leviathan is Litan, word for word", "finding": "'The LORD will punish Leviathan the fleeing serpent, Leviathan the twisting serpent, and slay the dragon in the sea.' The Ugaritic Baal Cycle names the same monster with the same epithets — Litan, 'the fleeing serpent (bthn brh), the twisting serpent (bthn ʿqltn)' — cognate for cognate, in the same order. The tightest Bible-to-Ugarit verbal parallel there is.", "category": "pagan", "citation": "Isa 27:1 ≅ Ugaritic KTU 1.5 I 1-3 (Litan / naḥaš bariḥ / ʿaqallaton). — pagan-influence", "tier": "DEMONSTRABLE"}], "40:3": [{"ref": "40:3", "title": "“A voice crying in the wilderness”", "finding": "'Prepare the way of the LORD' — the one part of Mark's opening citation (1:2-3) that really is from Isaiah. Mark's 'Isaiah' actually opens with Exodus + Malachi, and only this line is Isaianic.", "category": "ot-allusion", "citation": "Isa 40:3; cf. Mark 1:3. — nt-citation-sources", "tier": "DEMONSTRABLE"}], "42:1": [{"ref": "42:1", "title": "“My servant, my chosen, in whom I delight”", "finding": "The first Servant Song. Its language fuses with Psalm 2:7 in the voice at Jesus' baptism (Mark 1:11) and transfiguration (9:7): 'my beloved... in whom I am well pleased.'", "category": "ot-allusion", "citation": "Isa 42:1; cf. Mark 1:11, 9:7. — mark-origins", "tier": "STRONG-INFERENCE"}], "53:5": [{"ref": "53:5", "title": "The Suffering Servant", "finding": "'He was pierced for our transgressions... by his wounds we are healed... he bore the sin of many.' Isaiah 53 stands behind Jesus' 'ransom for many' (Mark 10:45) and the covenant cup 'poured out for many' (14:24) — though Mark alludes rather than quotes, and never states the death is 'for sins.'", "category": "ot-allusion", "citation": "Isa 53; cf. Mark 10:45, 14:24. — mark-origins", "tier": "STRONG-INFERENCE"}], "56:7": [{"ref": "56:7", "title": "“A house of prayer for all nations”", "finding": "Jesus' cry in the temple fuses this line with Jeremiah's 'den of robbers' (Jer 7:11). The quotation itself pronounces the temple's judgment.", "category": "ot-allusion", "citation": "Isa 56:7 + Jer 7:11; cf. Mark 11:17. — mark-origins", "tier": "DEMONSTRABLE"}]};